const WORDS = [{"word":"-weise","en":"suffix forming adverbs of manner (e.g. 'normally', 'fortunately')","ru":"суффикс, образующий наречия образа действия («обычно», «к счастью»)","vi":"-khôn ngoan","fa":"-عاقلانه","examples":[{"de":"Normalerweise stehe ich um sieben Uhr auf.","en":"Normally I get up at seven o'clock.","ru":"Обычно я встаю в семь часов.","vi":"Tôi thường thức dậy lúc bảy giờ.","fa":"من معمولا ساعت هفت بیدار می شوم."},{"de":"Glücklicherweise hat es nicht geregnet.","en":"Fortunately, it didn't rain.","ru":"К счастью, дождя не было.","vi":"May mắn là trời không mưa.","fa":"خوشبختانه باران نبارید."}]},{"word":"das A und O","en":"the be-all and end-all / the essential thing","ru":"самое главное, основа основ","vi":"điều quan trọng nhất và điều cuối cùng/điều thiết yếu","fa":"همه چیز و غایت همه چیز / چیز اساسی","examples":[{"de":"Übung ist das A und O beim Sprachenlernen.","en":"Practice is the be-all and end-all in language learning.","ru":"Практика — самое главное в изучении языков.","vi":"Thực hành là điều quan trọng nhất khi học một ngôn ngữ.","fa":"هنگام یادگیری یک زبان، تمرین همه چیز است."}]},{"word":"ab","en":"from; off/away","ru":"с; прочь","vi":"tắt","fa":"خاموش","examples":[{"de":"Ab morgen arbeite ich in einem neuen Büro.","en":"From tomorrow, I will work in a new office.","ru":"С завтрашнего дня я буду работать в новом офисе.","vi":"Bắt đầu từ ngày mai tôi sẽ làm việc ở văn phòng mới.","fa":"از فردا در دفتر جدید کار خواهم کرد."},{"de":"Der Knopf ist ab, ich muss ihn wieder annähen.","en":"The button has come off, I have to sew it back on.","ru":"Пуговица оторвалась, мне нужно пришить её обратно.","vi":"Nút bị tắt, tôi phải khâu lại.","fa":"دکمه خاموش است، باید دوباره آن را بدوزم."}]},{"word":"abbiegen","en":"to turn (off)","ru":"поворачивать","vi":"rẽ","fa":"چرخش","examples":[{"de":"An der nächsten Kreuzung müssen Sie links abbiegen.","en":"At the next intersection you have to turn left.","ru":"На следующем перекрёстке вам нужно повернуть налево.","vi":"Ở ngã tư tiếp theo bạn phải rẽ trái.","fa":"در تقاطع بعدی باید به چپ بپیچید."},{"de":"Er ist zu schnell abgebogen und fast gegen den Zaun gefahren.","en":"He turned too fast and almost crashed into the fence.","ru":"Он слишком быстро повернул и чуть не врезался в забор.","vi":"Anh ta quay quá nhanh và suýt tông vào hàng rào.","fa":"خیلی سریع چرخید و نزدیک بود به نرده برخورد کند."}]},{"word":"die Abbildung","en":"illustration; figure","ru":"иллюстрация; рисунок","vi":"hình minh họa","fa":"تصویر","examples":[{"de":"Auf Seite 12 finden Sie eine Abbildung des menschlichen Herzens.","en":"On page 12 you will find an illustration of the human heart.","ru":"На странице 12 вы найдёте иллюстрацию человеческого сердца.","vi":"Ở trang 12 bạn sẽ tìm thấy hình ảnh minh họa về trái tim con người.","fa":"در صفحه 12 تصویری از قلب انسان را خواهید دید."},{"de":"Die Abbildung zeigt, wie das Gerät zusammengebaut wird.","en":"The figure shows how the device is assembled.","ru":"На рисунке показано, как собирается устройство.","vi":"Hình minh họa cho thấy cách lắp ráp thiết bị.","fa":"تصویر نحوه مونتاژ دستگاه را نشان می دهد."}]},{"word":"das Abenteuer","en":"adventure","ru":"приключение","vi":"cuộc phiêu lưu","fa":"ماجراجویی","examples":[{"de":"Die Reise durch den Regenwald war ein echtes Abenteuer.","en":"The trip through the rainforest was a real adventure.","ru":"Путешествие по тропическому лесу было настоящим приключением.","vi":"Cuộc hành trình xuyên rừng nhiệt đới là một cuộc phiêu lưu thực sự.","fa":"سفر در جنگل های بارانی یک ماجراجویی واقعی بود."},{"de":"Kinder lieben Geschichten voller Abenteuer.","en":"Children love stories full of adventure.","ru":"Дети любят истории, полные приключений.","vi":"Trẻ em thích những câu chuyện đầy phiêu lưu.","fa":"کودکان داستان های پر از ماجراجویی را دوست دارند."}]},{"word":"abenteuerlich","en":"adventurous","ru":"полный приключений, авантюрный, рискованный","vi":"mạo hiểm","fa":"ماجراجو","examples":[{"de":"Die Fahrt durch die Berge war ziemlich abenteuerlich.","en":"The drive through the mountains was quite adventurous.","ru":"Поездка через горы была довольно рискованной.","vi":"Chuyến đi xuyên núi khá mạo hiểm.","fa":"رانندگی از میان کوه ها کاملاً ماجراجویانه بود."},{"de":"Sie mag abenteuerliche Reisen abseits der Touristenwege.","en":"She likes adventurous trips off the tourist trails.","ru":"Она любит авантюрные путешествия вдали от туристических троп.","vi":"Cô ấy thích những chuyến đi mạo hiểm ngoài đường mòn.","fa":"او سفرهای ماجراجویانه را دوست دارد."},{"de":"Unser Weg zum Hotel war abenteuerlicher als geplant.","en":"Our way to the hotel was more adventurous than planned.","ru":"Дорога до отеля оказалась более приключенческой, чем мы планировали.","vi":"Tuyến đường đến khách sạn của chúng tôi mạo hiểm hơn dự định.","fa":"مسیر ما به هتل پرماجراتر از برنامه ریزی بود."}]},{"word":"aber","en":"but","ru":"но","vi":"nhưng","fa":"اما","examples":[{"de":"Ich wollte kommen, aber ich hatte keine Zeit.","en":"I wanted to come, but I had no time.","ru":"Я хотел прийти, но у меня не было времени.","vi":"Tôi muốn đến nhưng không có thời gian.","fa":"می خواستم بیام ولی وقت نکردم."},{"de":"Das Kleid ist schön, aber sehr teuer.","en":"The dress is beautiful, but very expensive.","ru":"Платье красивое, но очень дорогое.","vi":"Chiếc váy rất đẹp nhưng rất đắt.","fa":"لباسش قشنگه ولی خیلی گرونه"}]},{"word":"abfahren","en":"to depart, to leave","ru":"отправляться, уезжать","vi":"khởi hành","fa":"رفتن","examples":[{"de":"Der Zug fährt um acht Uhr ab.","en":"The train departs at eight o'clock.","ru":"Поезд отправляется в восемь часов.","vi":"Tàu khởi hành lúc tám giờ.","fa":"قطار ساعت هشت حرکت می کند."},{"de":"Wir müssen früh abfahren, um den Stau zu vermeiden.","en":"We have to leave early to avoid the traffic jam.","ru":"Нам нужно выехать рано, чтобы избежать пробки.","vi":"Chúng tôi phải đi sớm để tránh ùn tắc giao thông.","fa":"برای جلوگیری از ترافیک باید زودتر حرکت کنیم."}]},{"word":"die Abfahrt","en":"departure","ru":"отправление, отъезд","vi":"sự ra đi","fa":"خروج","examples":[{"de":"Die Abfahrt des Busses verzögert sich um zehn Minuten.","en":"The bus's departure is delayed by ten minutes.","ru":"Отправление автобуса задерживается на десять минут.","vi":"Chuyến xe buýt khởi hành bị trễ mười phút.","fa":"حرکت اتوبوس ده دقیقه تاخیر دارد."},{"de":"Bitte seien Sie eine Stunde vor Abfahrt am Bahnhof.","en":"Please be at the station one hour before departure.","ru":"Пожалуйста, будьте на вокзале за час до отправления.","vi":"Vui lòng có mặt tại nhà ga một giờ trước khi khởi hành.","fa":"لطفا یک ساعت قبل از حرکت در ایستگاه حضور داشته باشید."}]},{"word":"der Abfall","en":"waste; garbage","ru":"мусор, отходы","vi":"sự lãng phí","fa":"زباله","examples":[{"de":"Bitte werfen Sie den Abfall in die richtige Tonne.","en":"Please throw the waste into the correct bin.","ru":"Пожалуйста, выбрасывайте мусор в правильный контейнер.","vi":"Hãy vứt rác vào đúng thùng rác.","fa":"لطفا زباله ها را در سطل مناسب بریزید."},{"de":"In der Küche produzieren wir jeden Tag viel Abfall.","en":"In the kitchen we produce a lot of waste every day.","ru":"На кухне мы каждый день производим много отходов.","vi":"Chúng ta thải ra rất nhiều rác thải trong nhà bếp mỗi ngày.","fa":"ما روزانه زباله های زیادی در آشپزخانه تولید می کنیم."}]},{"word":"der Abfalleimer","en":"rubbish bin, dustbin","ru":"мусорное ведро, урна","vi":"thùng rác","fa":"سطل زباله","examples":[{"de":"Wirf den Müll bitte in den Abfalleimer.","en":"Please throw the rubbish into the bin.","ru":"Пожалуйста, выбрось мусор в мусорное ведро.","vi":"Hãy vứt rác vào thùng rác.","fa":"لطفا زباله ها را در سطل زباله بیندازید."},{"de":"Der Abfalleimer in der Küche ist schon voll.","en":"The bin in the kitchen is already full.","ru":"Мусорное ведро на кухне уже полное.","vi":"Thùng rác trong bếp đã đầy rồi.","fa":"سطل زباله در آشپزخانه از قبل پر شده است."},{"de":"Neben jeder Bank steht ein Abfalleimer.","en":"There is a rubbish bin next to every bench.","ru":"Рядом с каждой скамейкой стоит урна.","vi":"Cạnh mỗi băng ghế đều có một thùng rác.","fa":"کنار هر نیمکتی یک سطل زباله وجود دارد."}]},{"word":"die Abfallvermeidung","en":"waste avoidance","ru":"сокращение отходов, предотвращение образования отходов","vi":"tránh lãng phí","fa":"اجتناب از زباله","examples":[{"de":"Abfallvermeidung beginnt schon beim Einkaufen.","en":"Waste avoidance starts when shopping.","ru":"Сокращение отходов начинается уже при покупках.","vi":"Tránh lãng phí bắt đầu bằng việc mua sắm.","fa":"اجتناب از ضایعات با خرید شروع می شود."},{"de":"Die Stadt setzt auf Abfallvermeidung statt Recycling.","en":"The city focuses on waste avoidance rather than recycling.","ru":"Город делает ставку на сокращение отходов, а не на переработку.","vi":"Thành phố tập trung vào việc ngăn chặn rác thải thay vì tái chế.","fa":"تمرکز این شهر به جای بازیافت، بر پیشگیری از زباله است."},{"de":"Mehrwegflaschen sind ein Beitrag zur Abfallvermeidung.","en":"Reusable bottles are a contribution to waste avoidance.","ru":"Многоразовые бутылки — вклад в сокращение отходов.","vi":"Chai tái sử dụng là một góp phần tránh lãng phí.","fa":"بطری های قابل استفاده مجدد کمکی به جلوگیری از ضایعات هستند."}]},{"word":"der Abflug","en":"departure (by air)","ru":"вылет (самолёта)","vi":"sự ra đi","fa":"خروج","examples":[{"de":"Der Abflug ist für acht Uhr morgens geplant.","en":"Departure is scheduled for eight in the morning.","ru":"Вылет запланирован на восемь утра.","vi":"Dự kiến khởi hành vào lúc tám giờ sáng.","fa":"حرکت برای ساعت هشت صبح برنامه ریزی شده است."},{"de":"Wir müssen zwei Stunden vor dem Abflug am Flughafen sein.","en":"We have to be at the airport two hours before departure.","ru":"Мы должны быть в аэропорту за два часа до вылета.","vi":"Chúng ta phải có mặt ở sân bay hai tiếng trước giờ khởi hành.","fa":"دو ساعت قبل از حرکت باید در فرودگاه باشیم."},{"de":"Der Abflug verzögerte sich wegen des Wetters.","en":"The departure was delayed because of the weather.","ru":"Вылет задержался из-за погоды.","vi":"Chuyến khởi hành bị trì hoãn do thời tiết.","fa":"به دلیل شرایط جوی حرکت با تاخیر انجام شد."}]},{"word":"das Abgas","en":"exhaust gas, emissions","ru":"выхлопные газы","vi":"khí thải","fa":"گاز اگزوز","examples":[{"de":"Die Abgase der Autos verschmutzen die Luft.","en":"The exhaust gases from cars pollute the air.","ru":"Выхлопные газы автомобилей загрязняют воздух.","vi":"Khí thải từ ô tô gây ô nhiễm không khí.","fa":"دود اگزوز خودروها هوا را آلوده می کند."},{"de":"Neue Motoren stoßen weniger Abgas aus.","en":"New engines emit less exhaust gas.","ru":"Новые двигатели выделяют меньше выхлопных газов.","vi":"Động cơ mới thải ra ít khí thải hơn.","fa":"موتورهای جدید گازهای خروجی کمتری تولید می کنند."},{"de":"In der Stadt riecht man oft die Abgase im Verkehr.","en":"In the city you often smell the exhaust fumes in the traffic.","ru":"В городе в потоке машин часто чувствуешь запах выхлопных газов.","vi":"Trong thành phố, bạn thường có thể ngửi thấy mùi khói thải từ giao thông.","fa":"در شهر اغلب بوی دود اگزوز ناشی از ترافیک را حس می کنید."}]},{"word":"Abgase","en":"exhaust fumes","ru":"выхлопные газы","vi":"Khí thải","fa":"دود اگزوز","examples":[{"de":"Die Abgase der Autos verschmutzen die Luft in der Stadt.","en":"The exhaust fumes from cars pollute the air in the city.","ru":"Выхлопные газы автомобилей загрязняют воздух в городе.","vi":"Khí thải từ ô tô gây ô nhiễm không khí trong thành phố.","fa":"دود اگزوز خودروها هوای شهر را آلوده می کند."},{"de":"Neue Motoren produzieren weniger Abgase als alte.","en":"New engines produce fewer exhaust fumes than old ones.","ru":"Новые двигатели производят меньше выхлопных газов, чем старые.","vi":"Động cơ mới tạo ra ít khí thải hơn động cơ cũ.","fa":"موتورهای جدید گازهای خروجی کمتری نسبت به موتورهای قدیمی تولید می کنند."}]},{"word":"abgeben","en":"to hand in; to give away","ru":"сдавать, отдавать","vi":"cho đi","fa":"تحویل دادن","examples":[{"de":"Ich muss meine Hausaufgabe bis Freitag abgeben.","en":"I have to hand in my homework by Friday.","ru":"Мне нужно сдать домашнее задание до пятницы.","vi":"Tôi phải nộp bài tập về nhà trước thứ Sáu.","fa":"تا جمعه باید تکالیفم را تحویل بدهم."},{"de":"Er hat sein altes Fahrrad an seinen Bruder abgegeben.","en":"He gave his old bike away to his brother.","ru":"Он отдал свой старый велосипед брату.","vi":"Anh ấy đã tặng chiếc xe đạp cũ của mình cho anh trai mình.","fa":"دوچرخه قدیمی خود را به برادرش داد."}]},{"word":"abhängen","en":"to depend (on)","ru":"зависеть (от)","vi":"phụ thuộc","fa":"بستگی دارد","examples":[{"de":"Es hängt vom Wetter ab, ob wir grillen.","en":"It depends on the weather whether we barbecue.","ru":"Это зависит от погоды, будем ли мы жарить на гриле.","vi":"Nó phụ thuộc vào thời tiết cho dù chúng ta nướng.","fa":"به آب و هوا بستگی دارد که کباب کنیم."},{"de":"Der Preis hängt von der Menge ab.","en":"The price depends on the quantity.","ru":"Цена зависит от количества.","vi":"Giá cả phụ thuộc vào số lượng.","fa":"قیمت بستگی به مقدار دارد."}]},{"word":"abhängig","en":"dependent (on)","ru":"зависимый (от)","vi":"phụ thuộc","fa":"وابسته","examples":[{"de":"Viele Studierende sind finanziell von ihren Eltern abhängig.","en":"Many students are financially dependent on their parents.","ru":"Многие студенты финансово зависимы от родителей.","vi":"Nhiều sinh viên phụ thuộc tài chính vào cha mẹ.","fa":"بسیاری از دانش آموزان از نظر مالی به والدین خود وابسته هستند."},{"de":"Der Ausflug ist vom Wetter abhängig.","en":"The trip is dependent on the weather.","ru":"Поездка зависит от погоды.","vi":"Chuyến tham quan phụ thuộc vào thời tiết.","fa":"سفر به آب و هوا بستگی دارد."},{"de":"Er ist von Nikotin abhängig geworden.","en":"He has become addicted to nicotine.","ru":"У него появилась зависимость от никотина.","vi":"Anh ấy trở nên nghiện nicotine.","fa":"او به نیکوتین معتاد شد."}]},{"word":"abheben","en":"to withdraw (money); to take off","ru":"снимать (деньги); взлетать","vi":"cất cánh","fa":"برخاستن","examples":[{"de":"Ich möchte 100 Euro von meinem Konto abheben.","en":"I would like to withdraw 100 euros from my account.","ru":"Я хочу снять 100 евро со своего счёта.","vi":"Tôi muốn rút 100 euro từ tài khoản của mình.","fa":"من می خواهم 100 یورو از حسابم برداشت کنم."},{"de":"Das Flugzeug hebt in zehn Minuten ab.","en":"The plane takes off in ten minutes.","ru":"Самолёт взлетает через десять минут.","vi":"Máy bay sẽ cất cánh trong mười phút nữa.","fa":"هواپیما ده دقیقه دیگر بلند می شود."}]},{"word":"abholen","en":"to pick up, to collect","ru":"забирать","vi":"nhặt lên","fa":"برداشتن","examples":[{"de":"Kannst du mich später vom Bahnhof abholen?","en":"Can you pick me up from the station later?","ru":"Ты можешь забрать меня позже с вокзала?","vi":"Bạn có thể đón tôi từ ga xe lửa sau được không?","fa":"آیا می توانید بعداً مرا از ایستگاه قطار ببرید؟"},{"de":"Ich muss das Paket bei der Post abholen.","en":"I have to pick up the package at the post office.","ru":"Мне нужно забрать посылку на почте.","vi":"Tôi phải nhận gói hàng ở bưu điện.","fa":"باید بسته را از اداره پست تحویل بگیرم."}]},{"word":"die Abholzung","en":"deforestation","ru":"вырубка лесов","vi":"nạn phá rừng","fa":"جنگل زدایی","examples":[{"de":"Die Abholzung der Wälder ist eine Ursache des Klimawandels.","en":"The deforestation of woodlands is one cause of climate change.","ru":"Вырубка лесов — одна из причин изменения климата.","vi":"Phá rừng là nguyên nhân gây ra biến đổi khí hậu.","fa":"جنگل زدایی یکی از دلایل تغییرات آب و هوایی است."},{"de":"Durch die Abholzung verlieren viele Tiere ihren Lebensraum.","en":"Through deforestation many animals lose their habitat.","ru":"Из-за вырубки лесов многие животные теряют среду обитания.","vi":"Nhiều loài động vật mất môi trường sống do nạn phá rừng.","fa":"بسیاری از حیوانات به دلیل جنگل زدایی زیستگاه خود را از دست می دهند."},{"de":"Umweltgruppen kämpfen gegen die illegale Abholzung im Regenwald.","en":"Environmental groups are fighting against the illegal deforestation in the rainforest.","ru":"Экологические группы борются против незаконной вырубки в тропическом лесу.","vi":"Các nhóm môi trường đang đấu tranh chống lại nạn phá rừng bất hợp pháp ở rừng nhiệt đới.","fa":"گروه های محیط زیست در حال مبارزه با جنگل زدایی غیرقانونی در جنگل های بارانی هستند."}]},{"word":"das Abitur","en":"school-leaving exam (German equivalent of A-levels)","ru":"аттестат зрелости, выпускной экзамен","vi":"bằng tốt nghiệp trung học","fa":"دیپلم دبیرستان","examples":[{"de":"Nächstes Jahr macht meine Schwester ihr Abitur.","en":"Next year my sister will take her Abitur (final exam).","ru":"В следующем году моя сестра сдаёт выпускные экзамены.","vi":"Em gái tôi sẽ tốt nghiệp trung học vào năm tới.","fa":"خواهرم سال آینده از دبیرستان فارغ التحصیل می شود."},{"de":"Ohne Abitur kann man in Deutschland nicht an der Universität studieren.","en":"Without the Abitur you cannot study at university in Germany.","ru":"Без аттестата зрелости нельзя учиться в университете в Германии.","vi":"Bạn không thể học đại học ở Đức nếu không có bằng tốt nghiệp trung học.","fa":"شما نمی توانید در آلمان بدون دیپلم دبیرستان در دانشگاه تحصیل کنید."}]},{"word":"die Abkühlung","en":"cooling, drop in temperature","ru":"похолодание; прохлада","vi":"sự hạ nhiệt","fa":"خنک شدن","examples":[{"de":"Nach dem Gewitter brachte der Wind eine angenehme Abkühlung.","en":"After the thunderstorm the wind brought a pleasant cooling.","ru":"После грозы ветер принёс приятную прохладу.","vi":"Nach dem Gewitter brachte der Wind eine angenehme Abkühlung.","fa":"پس از رعد و برق، باد یک اثر خنک کننده دلپذیر به ارمغان آورد."},{"de":"Für die nächsten Tage ist eine deutliche Abkühlung angekündigt.","en":"A clear drop in temperature is forecast for the next few days.","ru":"На ближайшие дни обещают заметное похолодание.","vi":"Dự báo sẽ có đợt giảm nhiệt đáng kể trong vài ngày tới.","fa":"برای چند روز آینده سرمای قابل توجهی پیش بینی می شود."},{"de":"Im See suchten wir bei der Hitze Abkühlung.","en":"In the heat we sought cooling in the lake.","ru":"В жару мы искали прохладу в озере.","vi":"Tôi thấy như vậy với Hitze Abkühlung.","fa":"سعی کردیم در گرما در دریاچه خنک شویم."}]},{"word":"ablaufen","en":"to expire; to proceed/run (its course); to run off","ru":"истекать (о сроке); проходить, протекать; вытекать","vi":"hết hạn","fa":"منقضی شود","examples":[{"de":"Mein Pass läuft nächsten Monat ab.","en":"My passport expires next month.","ru":"Мой паспорт истекает в следующем месяце.","vi":"Hộ chiếu của tôi sẽ hết hạn vào tháng tới.","fa":"پاسپورت من ماه آینده تمام می شود."},{"de":"Wie ist das Treffen abgelaufen?","en":"How did the meeting go?","ru":"Как прошла встреча?","vi":"Cuộc họp diễn ra thế nào?","fa":"جلسه چگونه پیش رفت؟"},{"de":"Die Frist ist bereits abgelaufen.","en":"The deadline has already passed.","ru":"Срок уже истёк.","vi":"Thời hạn đã hết.","fa":"مهلت قبلاً به پایان رسیده است."}]},{"word":"ablehnen","en":"to reject, to decline","ru":"отклонять, отказывать","vi":"từ chối","fa":"رد کردن","examples":[{"de":"Die Firma hat meine Bewerbung abgelehnt.","en":"The company rejected my application.","ru":"Компания отклонила моё заявление.","vi":"Công ty đã từ chối đơn đăng ký của tôi.","fa":"شرکت درخواست من را رد کرد."},{"de":"Er hat die Einladung zur Party abgelehnt.","en":"He declined the invitation to the party.","ru":"Он отклонил приглашение на вечеринку.","vi":"Anh ấy đã từ chối lời mời tới bữa tiệc.","fa":"او دعوت به مهمانی را رد کرد."}]},{"word":"abmachen","en":"to agree on; to remove","ru":"договариваться; снимать","vi":"giải quyết","fa":"حل و فصل شود","examples":[{"de":"Wir haben abgemacht, uns um sechs Uhr zu treffen.","en":"We agreed to meet at six o'clock.","ru":"Мы договорились встретиться в шесть часов.","vi":"Chúng tôi đồng ý gặp nhau lúc sáu giờ.","fa":"قرار گذاشتیم که ساعت شش همدیگر را ببینیم."},{"de":"Kannst du das Preisschild vom Geschenk abmachen?","en":"Can you remove the price tag from the gift?","ru":"Можешь снять ценник с подарка?","vi":"Bạn có thể lấy bảng giá ra khỏi món quà được không?","fa":"آیا می توانید برچسب قیمت را از روی هدیه بردارید؟"}]},{"word":"die Abmeldung","en":"deregistration; cancellation","ru":"снятие с учёта; отмена регистрации","vi":"việc hủy đăng ký","fa":"لغو ثبت نام","examples":[{"de":"Vor dem Wegzug ist eine Abmeldung nötig.","en":"Before moving away, deregistration is required.","ru":"Перед отъездом нужно сняться с учёта.","vi":"Bạn phải hủy đăng ký trước khi chuyển đi.","fa":"قبل از حرکت باید از ثبت نام خارج شوید."},{"de":"Die Abmeldung vom Newsletter geht ganz einfach.","en":"Unsubscribing from the newsletter is very easy.","ru":"Отписаться от рассылки очень просто.","vi":"Việc hủy đăng ký nhận bản tin rất dễ dàng.","fa":"لغو اشتراک از خبرنامه بسیار آسان است."}]},{"word":"abnehmen","en":"to lose weight; to take off/decrease","ru":"худеть; снимать; уменьшаться","vi":"giảm cân","fa":"کاهش وزن","examples":[{"de":"Sie hat in den letzten Monaten fünf Kilo abgenommen.","en":"She has lost five kilos in the last few months.","ru":"За последние месяцы она похудела на пять килограммов.","vi":"Cô ấy đã giảm được 5 kg trong vài tháng qua.","fa":"او در چند ماه گذشته پنج کیلو وزن کم کرده است."},{"de":"Die Temperaturen nehmen im Herbst langsam ab.","en":"Temperatures slowly decrease in autumn.","ru":"Осенью температура постепенно снижается.","vi":"Nhiệt độ giảm dần vào mùa thu.","fa":"دمای هوا در پاییز به آرامی کاهش می یابد."}]},{"word":"das Abonnement","en":"subscription","ru":"подписка, абонемент","vi":"đăng ký","fa":"اشتراک","examples":[{"de":"Mein Abonnement für die Zeitschrift läuft im Dezember ab.","en":"My subscription to the magazine expires in December.","ru":"Моя подписка на журнал заканчивается в декабре.","vi":"Việc đăng ký tạp chí của tôi sẽ hết hạn vào tháng 12.","fa":"اشتراک من در این مجله در ماه دسامبر به پایان می رسد."},{"de":"Wir haben ein Abonnement für das Theater gekauft.","en":"We bought a subscription for the theater.","ru":"Мы купили абонемент в театр.","vi":"Chúng tôi đã mua đăng ký xem rạp.","fa":"ما اشتراک تئاتر خریدیم."}]},{"word":"abonnieren","en":"to subscribe","ru":"подписываться","vi":"đăng ký","fa":"مشترک شوید","examples":[{"de":"Ich habe die Tageszeitung abonniert.","en":"I have subscribed to the daily newspaper.","ru":"Я подписался на ежедневную газету.","vi":"Tôi đã đặt mua dài hạn tờ báo hàng ngày.","fa":"من مشترک روزنامه روزانه شده ام."},{"de":"Viele Leute abonnieren heute Streaming-Dienste statt Zeitschriften.","en":"Many people today subscribe to streaming services instead of magazines.","ru":"Сегодня многие подписываются на стриминговые сервисы вместо журналов.","vi":"Ngày nay nhiều người đăng ký dịch vụ phát trực tuyến thay vì tạp chí.","fa":"امروزه بسیاری از مردم به جای مجلات، مشترک خدمات پخش جریانی می شوند."}]},{"word":"die Abreise","en":"departure (on a journey)","ru":"отъезд, отправление (в поездку)","vi":"sự ra đi","fa":"خروج","examples":[{"de":"Unsere Abreise ist für Sonntagmorgen geplant.","en":"Our departure is planned for Sunday morning.","ru":"Наш отъезд запланирован на утро воскресенья.","vi":"Chuyến khởi hành của chúng tôi dự kiến vào sáng Chủ nhật.","fa":"حرکت ما برای یکشنبه صبح برنامه ریزی شده است."},{"de":"Vor der Abreise müssen wir noch die Koffer packen.","en":"Before our departure we still have to pack the suitcases.","ru":"Перед отъездом нам ещё надо собрать чемоданы.","vi":"Trước khi rời đi, chúng tôi phải đóng gói hành lý của mình.","fa":"قبل از رفتن باید چمدان هایمان را ببندیم."},{"de":"Die Abreise verzögerte sich wegen des Sturms.","en":"The departure was delayed because of the storm.","ru":"Отъезд задержался из-за бури.","vi":"Chuyến khởi hành bị trì hoãn vì cơn bão.","fa":"حرکت به دلیل طوفان به تاخیر افتاد."}]},{"word":"die Absage","en":"cancellation, rejection","ru":"отказ, отклонение (заявки)","vi":"sự từ chối","fa":"رد کردن","examples":[{"de":"Leider habe ich eine Absage für die Stelle bekommen.","en":"Unfortunately I received a rejection for the job.","ru":"К сожалению, я получил отказ по вакансии.","vi":"Thật không may, tôi đã nhận được sự từ chối cho vị trí này.","fa":"متأسفانه من برای این سمت رد شدم."},{"de":"Die Absage des Konzerts war für viele eine Enttäuschung.","en":"The cancellation of the concert was a disappointment for many.","ru":"Отмена концерта стала для многих разочарованием.","vi":"Việc hủy bỏ buổi hòa nhạc khiến nhiều người thất vọng.","fa":"لغو کنسرت برای بسیاری ناامید کننده بود."},{"de":"Er schickte eine höfliche Absage per E-Mail.","en":"He sent a polite refusal by email.","ru":"Он прислал вежливый отказ по электронной почте.","vi":"Anh ấy đã gửi email từ chối một cách lịch sự.","fa":"او یک رد مودبانه را ایمیل کرد."}]},{"word":"absagen","en":"to cancel","ru":"отменять","vi":"hủy bỏ","fa":"لغو","examples":[{"de":"Wegen Regen mussten wir das Picknick absagen.","en":"Because of the rain we had to cancel the picnic.","ru":"Из-за дождя нам пришлось отменить пикник.","vi":"Chúng tôi phải hủy chuyến dã ngoại vì trời mưa.","fa":"به خاطر باران مجبور شدیم پیک نیک را لغو کنیم."},{"de":"Er hat den Termin beim Arzt kurzfristig abgesagt.","en":"He cancelled the doctor's appointment at short notice.","ru":"Он отменил приём у врача в последний момент.","vi":"Anh ấy đã hủy cuộc hẹn với bác sĩ trong thời gian ngắn.","fa":"او در کوتاه ترین زمان قرار ملاقات با پزشک را لغو کرد."}]},{"word":"der Abschied","en":"farewell, goodbye, parting","ru":"прощание, расставание","vi":"lời chia tay","fa":"خداحافظی","examples":[{"de":"Der Abschied von meinen Freunden fiel mir schwer.","en":"Saying goodbye to my friends was hard for me.","ru":"Прощание с друзьями далось мне тяжело.","vi":"Thật khó để tôi nói lời tạm biệt với bạn bè.","fa":"خداحافظی با دوستانم برایم سخت بود."},{"de":"Zum Abschied winkten wir vom Bahnsteig.","en":"As a farewell we waved from the platform.","ru":"На прощание мы махали с перрона.","vi":"Chúng tôi vẫy tay chào tạm biệt từ sân ga.","fa":"از روی سکو برای خداحافظی دست تکان دادیم."},{"de":"Sie nahm Abschied von ihrer alten Heimat.","en":"She bid farewell to her old homeland.","ru":"Она простилась со своей прежней родиной.","vi":"Cô nói lời tạm biệt với ngôi nhà cũ của mình.","fa":"او با خانه قدیمی خود خداحافظی کرد."}]},{"word":"abschleppen","en":"to tow away","ru":"отбуксировать, оттащить (автомобиль)","vi":"kéo đi","fa":"بکسل دور","examples":[{"de":"Mein Auto wurde gestern abgeschleppt.","en":"My car was towed away yesterday.","ru":"Вчера мою машину отбуксировали.","vi":"Xe của tôi đã được kéo ngày hôm qua.","fa":"ماشین من دیروز یدک کش شد."},{"de":"Der Wagen blieb liegen und musste abgeschleppt werden.","en":"The car broke down and had to be towed away.","ru":"Машина сломалась, и её пришлось отбуксировать.","vi":"Chiếc xe bị hỏng và phải kéo đi.","fa":"ماشین خراب شد و مجبور شد بکسل شود."},{"de":"Falsch geparkte Autos werden hier abgeschleppt.","en":"Wrongly parked cars are towed away here.","ru":"Неправильно припаркованные машины здесь эвакуируют.","vi":"Những chiếc xe đỗ trái phép sẽ bị kéo về đây.","fa":"خودروهای پارک شده غیرقانونی در اینجا یدک می کشند."}]},{"word":"der Abschluss","en":"conclusion; (school/university) degree","ru":"завершение; диплом","vi":"kết luận","fa":"نتیجه گیری","examples":[{"de":"Nach dem Abschluss ihres Studiums fand sie schnell eine Stelle.","en":"After completing her degree, she quickly found a job.","ru":"После окончания учёбы она быстро нашла работу.","vi":"Sau khi học xong, cô nhanh chóng tìm được việc làm.","fa":"پس از اتمام تحصیلاتش، به سرعت شغلی پیدا کرد."},{"de":"Zum Abschluss des Treffens haben alle noch einmal applaudiert.","en":"To conclude the meeting, everyone applauded once more.","ru":"В завершение встречи все ещё раз поаплодировали.","vi":"Kết thúc cuộc họp mọi người lại vỗ tay lần nữa.","fa":"در پایان جلسه دوباره همه کف زدند."}]},{"word":"das Abschlusszeugnis","en":"final certificate, diploma","ru":"аттестат об окончании, свидетельство","vi":"giấy chứng nhận tốt nghiệp","fa":"گواهی فارغ التحصیلی","examples":[{"de":"Mit dem Abschlusszeugnis kannst du dich bei Firmen bewerben.","en":"With the final certificate you can apply to companies.","ru":"С аттестатом об окончании ты можешь подавать заявки в фирмы.","vi":"Với bằng tốt nghiệp của bạn, bạn có thể nộp đơn vào các công ty.","fa":"با مدرک دیپلم خود می توانید برای شرکت ها درخواست دهید."},{"de":"Sie zeigte stolz ihr Abschlusszeugnis.","en":"She proudly showed her final certificate.","ru":"Она с гордостью показала свой аттестат об окончании.","vi":"Cô tự hào khoe tấm bằng tốt nghiệp của mình.","fa":"او با افتخار مدرک خود را نشان داد."},{"de":"Im Abschlusszeugnis stehen alle Noten der letzten Klasse.","en":"The final certificate lists all the grades of the last year.","ru":"В аттестате об окончании стоят все оценки последнего класса.","vi":"Tất cả các điểm của lớp cuối cùng được bao gồm trong chứng chỉ cuối cùng.","fa":"تمامی نمرات آخرین کلاس در گواهی پایانی گنجانده شده است."}]},{"word":"abschmecken","en":"to season to taste","ru":"доводить до вкуса, приправлять по вкусу","vi":"hương vị","fa":"طعم","examples":[{"de":"Schmeck die Suppe mit Salz und Pfeffer ab.","en":"Season the soup with salt and pepper to taste.","ru":"Доведи суп до вкуса солью и перцем.","vi":"Nêm súp với muối và hạt tiêu.","fa":"سوپ را با نمک و فلفل مزه دار کنید."},{"de":"Bevor du servierst, solltest du die Soße abschmecken.","en":"Before you serve, you should season the sauce to taste.","ru":"Прежде чем подавать, тебе следует довести соус до вкуса.","vi":"Trước khi dùng, bạn nên nếm thử nước sốt.","fa":"قبل از سرو باید سس را بچشید."},{"de":"Sie schmeckt das Gericht ab und gibt noch Kräuter dazu.","en":"She seasons the dish to taste and adds some herbs.","ru":"Она доводит блюдо до вкуса и добавляет ещё трав.","vi":"Cô nếm thử món ăn và thêm rau thơm vào.","fa":"او طعم غذا را می چشد و گیاهان را اضافه می کند."}]},{"word":"der Abschnitt","en":"section, segment","ru":"раздел, участок","vi":"phần","fa":"بخش","examples":[{"de":"Lesen Sie bitte den ersten Abschnitt des Textes noch einmal.","en":"Please read the first section of the text again.","ru":"Пожалуйста, прочитайте ещё раз первый раздел текста.","vi":"Xin vui lòng đọc lại phần đầu tiên của văn bản.","fa":"لطفا بخش اول متن را دوباره بخوانید."},{"de":"Auf diesem Abschnitt der Autobahn gilt Tempo 100.","en":"On this section of the highway a speed limit of 100 applies.","ru":"На этом участке автомагистрали действует ограничение скорости 100.","vi":"Tốc độ giới hạn là 100 km/h trên đoạn đường cao tốc này.","fa":"سرعت مجاز در این بخش از بزرگراه 100 کیلومتر در ساعت است."}]},{"word":"abschreiben","en":"to copy; to write off","ru":"списывать","vi":"viết tắt","fa":"حذف کردن","examples":[{"de":"Er hat die Antworten von seinem Nachbarn abgeschrieben.","en":"He copied the answers from his neighbor.","ru":"Он списал ответы у соседа.","vi":"Anh ta sao chép câu trả lời từ người hàng xóm của mình.","fa":"او پاسخ های همسایه اش را کپی کرد."},{"de":"Die Firma musste die alte Maschine abschreiben.","en":"The company had to write off the old machine.","ru":"Компании пришлось списать старую машину.","vi":"Công ty đã phải loại bỏ chiếc máy cũ.","fa":"شرکت مجبور شد ماشین قدیمی را بنویسد."}]},{"word":"der Absender","en":"sender","ru":"отправитель","vi":"người gửi","fa":"فرستنده","examples":[{"de":"Auf dem Umschlag stand kein Absender.","en":"There was no sender on the envelope.","ru":"На конверте не было указано отправителя.","vi":"Không có địa chỉ gửi lại trên phong bì.","fa":"هیچ آدرس برگشتی روی پاکت وجود نداشت."},{"de":"Bitte notieren Sie den Absender oben links auf dem Brief.","en":"Please note the sender in the top left of the letter.","ru":"Пожалуйста, укажите отправителя в верхнем левом углу письма.","vi":"Vui lòng ghi chú người gửi ở phía trên bên trái của bức thư.","fa":"لطفاً به فرستنده در سمت چپ بالای نامه توجه کنید."}]},{"word":"die Absenderin","en":"sender (female)","ru":"отправительница","vi":"người gửi","fa":"فرستنده","examples":[{"de":"Die Absenderin hatte ihre Adresse vergessen.","en":"The sender had forgotten her address.","ru":"Отправительница забыла указать свой адрес.","vi":"Người gửi đã quên địa chỉ của cô ấy.","fa":"فرستنده آدرس خود را فراموش کرده بود."},{"de":"Auf der Karte stand der Name der Absenderin.","en":"The sender's name was written on the card.","ru":"На открытке стояло имя отправительницы.","vi":"Tên người gửi được viết trên tấm thiệp.","fa":"نام فرستنده روی کارت نوشته شده بود."},{"de":"Die Absenderin wartet auf eine Antwort.","en":"The sender is waiting for a reply.","ru":"Отправительница ждёт ответа.","vi":"Người gửi đang chờ trả lời.","fa":"فرستنده منتظر پاسخ است."}]},{"word":"die Absicht","en":"intention","ru":"намерение","vi":"ý định","fa":"قصد","examples":[{"de":"Es war nicht meine Absicht, dich zu ärgern.","en":"It was not my intention to annoy you.","ru":"У меня не было намерения тебя раздражать.","vi":"Tôi không có ý định làm bạn khó chịu.","fa":"قصدم ناراحت کردنت نبود"},{"de":"Sie hat die Absicht, im Sommer nach Spanien zu ziehen.","en":"She intends to move to Spain in the summer.","ru":"Она намерена переехать в Испанию летом.","vi":"Cô dự định chuyển đến Tây Ban Nha vào mùa hè.","fa":"او قصد دارد در تابستان به اسپانیا برود."}]},{"word":"absolut","en":"absolute(ly)","ru":"абсолютный, абсолютно","vi":"tuyệt đối","fa":"مطلقا","examples":[{"de":"Das ist absolut unmöglich.","en":"That is absolutely impossible.","ru":"Это абсолютно невозможно.","vi":"Điều đó là hoàn toàn không thể.","fa":"که کاملا غیر ممکن است."},{"de":"Ich bin mir absolut sicher, dass ich den Schlüssel hier gelassen habe.","en":"I am absolutely sure that I left the key here.","ru":"Я абсолютно уверен, что оставил ключ здесь.","vi":"Tôi hoàn toàn chắc chắn rằng tôi đã để chìa khóa ở đây.","fa":"من کاملاً مطمئن هستم که کلید را اینجا گذاشته ام."}]},{"word":"abstimmen","en":"to vote; to coordinate","ru":"голосовать; согласовывать","vi":"bỏ phiếu","fa":"رای دادن","examples":[{"de":"Am Sonntag stimmen wir über das neue Gesetz ab.","en":"On Sunday we vote on the new law.","ru":"В воскресенье мы голосуем по новому закону.","vi":"Vào Chủ Nhật chúng ta sẽ bỏ phiếu về luật mới.","fa":"روز یکشنبه به قانون جدید رای خواهیم داد."},{"de":"Wir müssen unsere Termine noch miteinander abstimmen.","en":"We still need to coordinate our schedules with each other.","ru":"Нам ещё нужно согласовать наши сроки друг с другом.","vi":"Chúng tôi vẫn phải sắp xếp các cuộc hẹn với nhau.","fa":"ما هنوز باید قرارهایمان را با یکدیگر هماهنگ کنیم."}]},{"word":"die Abstimmung","en":"vote; ballot","ru":"голосование","vi":"cuộc bỏ phiếu","fa":"رای","examples":[{"de":"Die Abstimmung über das Gesetz findet morgen statt.","en":"The vote on the law takes place tomorrow.","ru":"Голосование по закону состоится завтра.","vi":"Cuộc bỏ phiếu về luật sẽ diễn ra vào ngày mai.","fa":"رای گیری این قانون فردا انجام می شود."},{"de":"Bei der Abstimmung gab es eine knappe Mehrheit.","en":"In the vote there was a narrow majority.","ru":"При голосовании было незначительное большинство.","vi":"Có một đa số hẹp trong cuộc bỏ phiếu.","fa":"اکثریت محدود در رای گیری وجود داشت."},{"de":"Alle Abgeordneten nahmen an der Abstimmung teil.","en":"All members took part in the vote.","ru":"Все депутаты приняли участие в голосовании.","vi":"Tất cả các nghị sĩ đều tham gia bỏ phiếu.","fa":"همه نمایندگان در رای گیری شرکت کردند."}]},{"word":"der Abt","en":"abbot","ru":"аббат (настоятель монастыря)","vi":"trụ trì","fa":"ابی","examples":[{"de":"Der Abt leitet das Kloster seit zwanzig Jahren.","en":"The abbot has led the monastery for twenty years.","ru":"Аббат руководит монастырём уже двадцать лет.","vi":"Vị trụ trì đã điều hành tu viện được hai mươi năm.","fa":"ابا بیست سال است که صومعه را اداره می کند."},{"de":"Die Mönche gehorchten dem Abt.","en":"The monks obeyed the abbot.","ru":"Монахи повиновались аббату.","vi":"Các tu sĩ vâng lời trụ trì.","fa":"راهبان از ابی اطاعت کردند."},{"de":"Der neue Abt wurde von den Brüdern gewählt.","en":"The new abbot was elected by the brothers.","ru":"Нового аббата избрали братья.","vi":"Vị trụ trì mới do anh em bầu ra.","fa":"رهبر جدید توسط برادران انتخاب شد."}]},{"word":"die Abteilung","en":"department","ru":"отдел","vi":"khoa","fa":"بخش","examples":[{"de":"Er arbeitet in der Abteilung für Marketing.","en":"He works in the marketing department.","ru":"Он работает в отделе маркетинга.","vi":"Anh ấy làm việc ở bộ phận tiếp thị.","fa":"او در بخش بازاریابی کار می کند."},{"de":"Die Schuhe finden Sie in der Abteilung im zweiten Stock.","en":"You will find the shoes in the department on the second floor.","ru":"Обувь вы найдёте в отделе на третьем этаже.","vi":"Những đôi giày có thể được tìm thấy trong gian hàng trên tầng hai.","fa":"کفش ها را می توان در بخش طبقه دوم پیدا کرد."}]},{"word":"der Abwart","en":"caretaker, janitor","ru":"смотритель, дворник","vi":"người canh gác","fa":"نگهبان","examples":[{"de":"Der Abwart repariert die kaputte Lampe im Treppenhaus.","en":"The caretaker is repairing the broken lamp in the stairwell.","ru":"Смотритель ремонтирует сломанную лампу в подъезде.","vi":"Người chăm sóc sửa chữa chiếc đèn bị hỏng ở cầu thang.","fa":"سرایدار لامپ شکسته راه پله را تعمیر می کند."},{"de":"Wenn die Heizung nicht funktioniert, rufen Sie bitte den Abwart an.","en":"If the heating doesn't work, please call the caretaker.","ru":"Если отопление не работает, позвоните, пожалуйста, смотрителю.","vi":"Nếu hệ thống sưởi không hoạt động, vui lòng gọi cho người bảo trì.","fa":"اگر گرمایش کار نمی کند، لطفا با تعمیرکار تماس بگیرید."}]},{"word":"die Abwartin","en":"caretaker, janitor (female, Swiss)","ru":"смотрительница дома, комендант (швейц., ж.)","vi":"cô hầu bàn","fa":"پیشخدمت","examples":[{"de":"Die Abwartin schließt abends das Schulhaus ab.","en":"The caretaker locks up the school building in the evening.","ru":"По вечерам смотрительница запирает школьное здание.","vi":"Người trông coi khóa cửa trường học vào buổi tối.","fa":"سرایدار عصر ساختمان مدرسه را قفل می کند."},{"de":"Unsere Abwartin ist sehr freundlich und hilfsbereit.","en":"Our caretaker is very friendly and helpful.","ru":"Наша смотрительница очень приветлива и готова помочь.","vi":"Tiếp viên của chúng tôi rất thân thiện và hữu ích.","fa":"مهماندار ما بسیار دوستانه و مفید است."},{"de":"Die Abwartin meldete den Schaden der Hausverwaltung.","en":"The caretaker reported the damage to the building management.","ru":"Смотрительница сообщила о повреждении в управляющую компанию.","vi":"Người chăm sóc đã báo cáo thiệt hại cho ban quản lý tài sản.","fa":"سرایدار خسارت وارده به مدیریت اموال را گزارش کرد."}]},{"word":"abwärts","en":"downward(s)","ru":"вниз","vi":"đi xuống","fa":"به سمت پایین","examples":[{"de":"Der Weg führt steil abwärts zum See.","en":"The path leads steeply downward to the lake.","ru":"Тропа круто спускается вниз к озеру.","vi":"Con đường dẫn dốc xuống hồ.","fa":"مسیر با شیب تند به سمت دریاچه منتهی می شود."},{"de":"Mit der Wirtschaft geht es seit Monaten abwärts.","en":"The economy has been going downhill for months.","ru":"Экономика уже несколько месяцев идёт на спад.","vi":"Nền kinh tế đã đi xuống trong nhiều tháng.","fa":"ماه هاست که اقتصاد در حال نزول است."}]},{"word":"abwaschen","en":"to wash up, to wash off","ru":"мыть посуду; смывать","vi":"rửa sạch","fa":"شستن","examples":[{"de":"Nach dem Essen muss noch das Geschirr abgewaschen werden.","en":"After the meal, the dishes still need to be washed up.","ru":"После еды ещё нужно вымыть посуду.","vi":"Ăn xong vẫn phải rửa bát.","fa":"پس از صرف غذا، ظروف هنوز باید شسته شوند."},{"de":"Sie wusch sich den Schmutz von den Händen ab.","en":"She washed the dirt off her hands.","ru":"Она смыла грязь с рук.","vi":"Cô rửa sạch bụi bẩn trên tay.","fa":"خاک را از روی دستانش شست."}]},{"word":"die Abwechslung","en":"variety, change","ru":"разнообразие, перемена","vi":"sự đa dạng","fa":"تنوع","examples":[{"de":"Zur Abwechslung gehen wir heute tanzen.","en":"For a change we're going dancing today.","ru":"Для разнообразия мы сегодня идём танцевать.","vi":"Để thay đổi, hôm nay chúng ta sẽ khiêu vũ.","fa":"برای تغییر، امروز می رقصیم."},{"de":"Ein bisschen Abwechslung tut gut.","en":"A bit of variety does you good.","ru":"Немного разнообразия идёт на пользу.","vi":"Một chút đa dạng là tốt.","fa":"کمی تنوع خوبه"},{"de":"Der Alltag bietet wenig Abwechslung.","en":"Everyday life offers little variety.","ru":"Будни дают мало разнообразия.","vi":"Cuộc sống hàng ngày có rất ít sự đa dạng.","fa":"زندگی روزمره تنوع کمی دارد."}]},{"word":"abwechslungsreich","en":"varied","ru":"разнообразный","vi":"đa dạng","fa":"متنوع","examples":[{"de":"Eine abwechslungsreiche Ernährung hält dich gesund.","en":"A varied diet keeps you healthy.","ru":"Разнообразное питание сохраняет здоровье.","vi":"Một chế độ ăn uống đa dạng giúp bạn khỏe mạnh.","fa":"رژیم غذایی متنوع شما را سالم نگه می دارد."},{"de":"Seine Arbeit ist abwechslungsreich und nie langweilig.","en":"His work is varied and never boring.","ru":"Его работа разнообразна и никогда не бывает скучной.","vi":"Công việc của anh rất đa dạng và không bao giờ nhàm chán.","fa":"کار او متنوع است و هرگز خسته کننده نیست."},{"de":"Wir hatten einen abwechslungsreichen Urlaub.","en":"We had a varied holiday.","ru":"У нас был разнообразный отпуск.","vi":"Chúng tôi đã có một kỳ nghỉ đa dạng.","fa":"تعطیلات متنوعی داشتیم."}]},{"word":"abwesend","en":"absent","ru":"отсутствующий","vi":"vắng mặt","fa":"غایب","examples":[{"de":"Drei Schüler waren heute abwesend.","en":"Three students were absent today.","ru":"Три ученика сегодня отсутствовали.","vi":"Hôm nay có 3 học sinh vắng mặt.","fa":"سه دانش آموز امروز غایب بودند."},{"de":"Er wirkte während des Gesprächs völlig abwesend.","en":"He seemed completely absent-minded during the conversation.","ru":"Во время разговора он казался совершенно отсутствующим.","vi":"Anh ấy dường như hoàn toàn vắng mặt trong suốt cuộc trò chuyện.","fa":"در طول مکالمه کاملاً غایب به نظر می رسید."}]},{"word":"der Account","en":"an account on a website or social network","ru":"аккаунт, учётная запись (на сайте или в соцсети)","vi":"tài khoản","fa":"حساب کاربری","examples":[{"de":"Du musst als Erstes einen Account erstellen.","en":"The first thing you have to do is create an account.","ru":"Первое, что нужно сделать, — создать аккаунт.","vi":"Điều đầu tiên bạn cần làm là tạo một tài khoản.","fa":"اولین کاری که باید انجام دهید این است که یک حساب کاربری ایجاد کنید."},{"de":"Mein Account wurde gesperrt, weil ich das Passwort dreimal falsch eingegeben habe.","en":"My account was blocked because I entered the password incorrectly three times.","ru":"Мой аккаунт заблокировали, потому что я трижды неправильно ввёл пароль.","vi":"Tài khoản của tôi đã bị khóa vì tôi nhập sai mật khẩu ba lần.","fa":"اکانت من مسدود شد چون رمز عبور را سه بار اشتباه وارد کردم."},{"de":"Du kannst dich mit demselben Account auf mehreren Geräten einloggen.","en":"You can log in to several devices with the same account.","ru":"С одним и тем же аккаунтом можно войти на нескольких устройствах.","vi":"Bạn có thể đăng nhập bằng cùng một tài khoản trên nhiều thiết bị.","fa":"شما می توانید با یک حساب کاربری در چندین دستگاه وارد شوید."}]},{"word":"achten","en":"to pay attention to; to respect","ru":"обращать внимание; уважать","vi":"chú ý","fa":"توجه کنید","examples":[{"de":"Achten Sie bitte auf die Straßenschilder.","en":"Please pay attention to the road signs.","ru":"Пожалуйста, обращайте внимание на дорожные знаки.","vi":"Please pay attention to the street signs.","fa":"لطفا به تابلوهای خیابان توجه کنید."},{"de":"Wir sollten die Meinung anderer Menschen achten.","en":"We should respect the opinions of other people.","ru":"Нам следует уважать мнение других людей.","vi":"Chúng ta nên tôn trọng ý kiến ​​của người khác.","fa":"ما باید به نظرات دیگران احترام بگذاریم."}]},{"word":"die Achtsamkeit","en":"mindfulness","ru":"осознанность, внимательность","vi":"chánh niệm","fa":"ذهن آگاهی","examples":[{"de":"Yoga übt man am besten mit voller Achtsamkeit.","en":"Yoga is best practised with full mindfulness.","ru":"Йогой лучше всего заниматься с полной осознанностью.","vi":"Yoga được thực hành tốt nhất với chánh niệm đầy đủ.","fa":"یوگا بهتر است با تمرکز کامل انجام شود."},{"de":"Achtsamkeit bedeutet, ganz im Moment zu sein.","en":"Mindfulness means being completely in the moment.","ru":"Осознанность означает полностью быть в моменте.","vi":"Chánh niệm có nghĩa là hoàn toàn ở trong thời điểm hiện tại.","fa":"ذهن آگاهی یعنی کاملا در لحظه بودن."},{"de":"Mit etwas Achtsamkeit bemerkst du jede Bewegung deines Körpers.","en":"With a little mindfulness you notice every movement of your body.","ru":"С небольшой внимательностью ты замечаешь каждое движение своего тела.","vi":"Với một chút chánh niệm, bạn sẽ nhận thấy mọi chuyển động của cơ thể mình.","fa":"با کمی تمرکز متوجه هر حرکت بدن خود خواهید شد."}]},{"word":"die Addition","en":"addition","ru":"сложение","vi":"sự bổ sung","fa":"علاوه بر این","examples":[{"de":"Die Addition zweier Zahlen ist die einfachste Rechenart.","en":"The addition of two numbers is the simplest arithmetic operation.","ru":"Сложение двух чисел — самое простое арифметическое действие.","vi":"Cộng hai số là hình thức tính toán đơn giản nhất.","fa":"جمع کردن دو عدد ساده ترین روش محاسبه است."},{"de":"In der Grundschule lernt man zuerst die Addition.","en":"In primary school you first learn addition.","ru":"В начальной школе сначала учат сложению.","vi":"Ở trường tiểu học, lần đầu tiên bạn học phép cộng.","fa":"در دبستان ابتدا جمع را یاد می گیرید."},{"de":"Bei der Addition kommt es nicht auf die Reihenfolge an.","en":"With addition the order does not matter.","ru":"При сложении порядок не важен.","vi":"Khi nói đến phép cộng, thứ tự không quan trọng.","fa":"وقتی صحبت از اضافه می شود، ترتیب مهم نیست."}]},{"word":"die Adoption","en":"adoption","ru":"усыновление, удочерение","vi":"việc nhận con nuôi","fa":"پذیرش","examples":[{"de":"Nach langem Warten wurde die Adoption endlich genehmigt.","en":"After a long wait the adoption was finally approved.","ru":"После долгого ожидания усыновление наконец одобрили.","vi":"Sau một thời gian dài chờ đợi, việc nhận con nuôi cuối cùng đã được chấp thuận.","fa":"پس از مدت ها انتظار، سرانجام فرزندخواندگی تایید شد."},{"de":"Durch die Adoption bekam das Kind eine liebevolle Familie.","en":"Through the adoption the child got a loving family.","ru":"Благодаря усыновлению ребёнок обрёл любящую семью.","vi":"Thông qua việc nhận con nuôi, đứa trẻ đã tìm được một gia đình yêu thương.","fa":"از طریق فرزندخواندگی، کودک خانواده ای دوست داشتنی پیدا کرد."},{"de":"Die Adoption eines Kindes ist mit vielen Formalitäten verbunden.","en":"The adoption of a child involves many formalities.","ru":"Усыновление ребёнка связано со множеством формальностей.","vi":"Việc nhận con nuôi bao gồm nhiều thủ tục.","fa":"فرزندخواندگی شامل تشریفات بسیاری است."}]},{"word":"die Adresse","en":"address","ru":"адрес","vi":"địa chỉ","fa":"آدرس","examples":[{"de":"Wie lautet Ihre neue Adresse?","en":"What is your new address?","ru":"Какой у вас новый адрес?","vi":"Địa chỉ mới của bạn là gì?","fa":"آدرس جدید شما چیست؟"},{"de":"Ich habe die Adresse des Hotels notiert.","en":"I noted down the address of the hotel.","ru":"Я записал адрес отеля.","vi":"Tôi đã viết địa chỉ của khách sạn.","fa":"آدرس هتل را یادداشت کردم."}]},{"word":"ähnlich","en":"similar","ru":"похожий, подобный","vi":"tương tự","fa":"مشابه","examples":[{"de":"Die beiden Schwestern sehen sich sehr ähnlich.","en":"The two sisters look very similar to each other.","ru":"Обе сестры очень похожи друг на друга.","vi":"Hai chị em trông rất giống nhau.","fa":"این دو خواهر خیلی شبیه هم هستند."},{"de":"Ich habe ein ähnliches Problem wie du.","en":"I have a similar problem to yours.","ru":"У меня похожая проблема, как у тебя.","vi":"Tôi có một vấn đề tương tự như bạn.","fa":"من هم مثل شما مشکلی دارم"}]},{"word":"die Ahnung","en":"idea, notion, clue","ru":"представление, догадка","vi":"linh cảm","fa":"تصور؛ سرنخ","examples":[{"de":"Ich habe keine Ahnung, wo meine Schlüssel sind.","en":"I have no idea where my keys are.","ru":"Я понятия не имею, где мои ключи.","vi":"Tôi không biết chìa khóa của mình ở đâu.","fa":"من نمی دانم کلیدهای من کجا هستند."},{"de":"Sie hatte eine Ahnung, dass etwas nicht stimmte.","en":"She had a hunch that something was wrong.","ru":"У неё было предчувствие, что что-то не так.","vi":"Cô linh cảm có điều gì đó không ổn.","fa":"او تصور می کرد که چیزی اشتباه است."}]},{"word":"die Akademie","en":"academy","ru":"академия","vi":"học viện","fa":"آکادمی","examples":[{"de":"Platon gründete in Athen eine berühmte Akademie.","en":"Plato founded a famous academy in Athens.","ru":"Платон основал в Афинах знаменитую академию.","vi":"Plato thành lập một học viện nổi tiếng ở Athens.","fa":"افلاطون آکادمی معروفی را در آتن تأسیس کرد."},{"de":"Sie wurde an einer renommierten Akademie für Musik ausgebildet.","en":"She was trained at a renowned academy of music.","ru":"Она получила образование в известной музыкальной академии.","vi":"Cô được đào tạo tại một học viện âm nhạc nổi tiếng.","fa":"او در یک آکادمی موسیقی مشهور آموزش دید."},{"de":"Die Akademie der Wissenschaften veröffentlicht jedes Jahr neue Studien.","en":"The academy of sciences publishes new studies every year.","ru":"Академия наук ежегодно публикует новые исследования.","vi":"Viện Hàn lâm Khoa học công bố các nghiên cứu mới hàng năm.","fa":"فرهنگستان علوم هر سال مطالعات جدیدی را منتشر می کند."}]},{"word":"die Akropolis","en":"acropolis","ru":"акрополь","vi":"Acropolis","fa":"آکروپولیس","examples":[{"de":"Die Akropolis von Athen ist ein Symbol der antiken Welt.","en":"The Acropolis of Athens is a symbol of the ancient world.","ru":"Афинский Акрополь — символ античного мира.","vi":"Acropolis của Athens là một biểu tượng của thế giới cổ đại.","fa":"آکروپولیس آتن نمادی از جهان باستان است."},{"de":"Wir haben gestern die Akropolis besichtigt und viele Fotos gemacht.","en":"Yesterday we visited the Acropolis and took many photos.","ru":"Вчера мы осмотрели Акрополь и сделали много фотографий.","vi":"Hôm qua chúng tôi đã đến thăm Acropolis và chụp rất nhiều ảnh.","fa":"دیروز از آکروپلیس دیدن کردیم و عکس های زیادی گرفتیم."},{"de":"Vom Hügel aus konnten wir die Akropolis deutlich sehen.","en":"From the hill we could see the Acropolis clearly.","ru":"С холма мы отчётливо видели Акрополь.","vi":"Từ trên đồi chúng tôi có thể nhìn thấy rõ Acropolis.","fa":"از روی تپه می‌توانستیم آکروپولیس را به وضوح ببینیم."}]},{"word":"die Aktion","en":"action; campaign, promotion","ru":"акция; действие","vi":"the action","fa":"عمل","examples":[{"de":"Der Supermarkt hat diese Woche eine Aktion mit reduzierten Preisen.","en":"The supermarket has a promotion with reduced prices this week.","ru":"В этом магазине на этой неделе акция со сниженными ценами.","vi":"Der Supermarkt hat diese Woche eine Aktion mit reduzierten Preisen.","fa":"این سوپرمارکت در این هفته یک تبلیغ با کاهش قیمت دارد."},{"de":"Die Feuerwehr startete sofort eine Aktion zur Rettung der Tiere.","en":"The fire department immediately launched an action to rescue the animals.","ru":"Пожарная служба немедленно начала акцию по спасению животных.","vi":"Lực lượng cứu hỏa ngay lập tức triển khai chiến dịch giải cứu các con vật.","fa":"آتش نشانی بلافاصله عملیات نجات حیوانات را آغاز کرد."}]},{"word":"aktiv","en":"active","ru":"активный","vi":"hoạt động","fa":"فعال","examples":[{"de":"Meine Großmutter ist trotz ihres Alters noch sehr aktiv.","en":"My grandmother is still very active despite her age.","ru":"Моя бабушка, несмотря на возраст, всё ещё очень активна.","vi":"Bà tôi vẫn còn rất năng động dù tuổi đã cao.","fa":"مادربزرگ من با وجود سنش هنوز خیلی فعال است."},{"de":"Er beteiligt sich aktiv an der Diskussion.","en":"He actively participates in the discussion.","ru":"Он активно участвует в обсуждении.","vi":"Anh ấy tích cực tham gia vào cuộc thảo luận.","fa":"او فعالانه در بحث شرکت می کند."}]},{"word":"die Aktivität","en":"activity","ru":"деятельность, активность, занятие","vi":"hoạt động","fa":"فعالیت","examples":[{"de":"Sport ist eine gesunde Aktivität.","en":"Sport is a healthy activity.","ru":"Спорт — это полезное занятие.","vi":"Thể thao là một hoạt động lành mạnh.","fa":"ورزش یک فعالیت سالم است."},{"de":"Im Sommer bietet das Hotel viele Aktivitäten an.","en":"In summer the hotel offers many activities.","ru":"Летом отель предлагает много развлечений.","vi":"Vào mùa hè, khách sạn cung cấp nhiều hoạt động.","fa":"در تابستان، هتل فعالیت های بسیاری را ارائه می دهد."},{"de":"Ihre Aktivität im Verein ist sehr geschätzt.","en":"Her activity in the club is much appreciated.","ru":"Её активность в клубе очень ценят.","vi":"Hoạt động của bạn trong câu lạc bộ được đánh giá rất cao.","fa":"فعالیت شما در باشگاه بسیار قابل تقدیر است."}]},{"word":"aktualisieren","en":"to update","ru":"обновлять","vi":"cập nhật","fa":"به روز رسانی کنید","examples":[{"de":"Du solltest die App regelmäßig aktualisieren.","en":"You should update the app regularly.","ru":"Тебе следует регулярно обновлять приложение.","vi":"Bạn nên cập nhật ứng dụng thường xuyên.","fa":"شما باید برنامه را به طور منظم به روز کنید."},{"de":"Nach dem Neustart wird das Programm aktualisiert.","en":"After the restart the program gets updated.","ru":"После перезапуска программа обновляется.","vi":"Sau khi khởi động lại, chương trình sẽ được cập nhật.","fa":"پس از راه اندازی مجدد، برنامه به روز می شود."},{"de":"Hast du schon aktualisiert, oder läuft noch die alte Version?","en":"Have you already updated, or is the old version still running?","ru":"Ты уже обновил, или ещё работает старая версия?","vi":"Bạn đã cập nhật chưa hay vẫn đang chạy phiên bản cũ?","fa":"آیا قبلاً به روز رسانی کرده اید یا هنوز نسخه قدیمی را اجرا می کنید؟"}]},{"word":"die Aktualisierung","en":"update; refresh","ru":"обновление","vi":"bản cập nhật","fa":"به روز رسانی","examples":[{"de":"Die Aktualisierung der App behebt mehrere Fehler.","en":"The update of the app fixes several bugs.","ru":"Обновление приложения исправляет несколько ошибок.","vi":"Cập nhật ứng dụng sẽ sửa một số lỗi.","fa":"به روز رسانی برنامه چندین باگ را برطرف می کند."},{"de":"Bitte warte, bis die Aktualisierung abgeschlossen ist.","en":"Please wait until the update is complete.","ru":"Пожалуйста, подожди, пока обновление завершится.","vi":"Vui lòng đợi quá trình cập nhật hoàn tất.","fa":"لطفا منتظر بمانید تا به روز رسانی کامل شود."},{"de":"Nach der Aktualisierung sieht die Oberfläche ganz anders aus.","en":"After the update the interface looks quite different.","ru":"После обновления интерфейс выглядит совсем иначе.","vi":"Sau khi cập nhật, giao diện trông hoàn toàn khác.","fa":"پس از به روز رسانی، رابط کاربری کاملاً متفاوت به نظر می رسد."}]},{"word":"aktuell","en":"current, up-to-date","ru":"актуальный, текущий","vi":"hiện tại","fa":"در حال حاضر","examples":[{"de":"Das ist die aktuelle Ausgabe der Zeitschrift.","en":"This is the current issue of the magazine.","ru":"Это текущий выпуск журнала.","vi":"Đây là số hiện tại của tạp chí.","fa":"این شماره فعلی مجله است."},{"de":"Die aktuelle Situation macht mir Sorgen.","en":"The current situation worries me.","ru":"Текущая ситуация меня беспокоит.","vi":"The current situation worries me.","fa":"وضعیت فعلی من را نگران می کند."}]},{"word":"akzeptieren","en":"to accept","ru":"принимать, соглашаться","vi":"chấp nhận","fa":"قبول کنید","examples":[{"de":"Er konnte die Entscheidung seines Chefs nicht akzeptieren.","en":"He could not accept his boss's decision.","ru":"Он не мог принять решение своего начальника.","vi":"Anh không thể chấp nhận quyết định của ông chủ.","fa":"او نمی توانست تصمیم رئیسش را بپذیرد."},{"de":"Wir akzeptieren auch Zahlungen mit Kreditkarte.","en":"We also accept payments by credit card.","ru":"Мы также принимаем оплату кредитной картой.","vi":"Chúng tôi cũng chấp nhận thanh toán bằng thẻ tín dụng.","fa":"ما همچنین پرداخت با کارت اعتباری را می پذیریم."}]},{"word":"der Alarm","en":"alarm","ru":"тревога, сигнализация","vi":"báo động","fa":"زنگ هشدار","examples":[{"de":"Plötzlich ging der Alarm im Gebäude los.","en":"Suddenly the alarm went off in the building.","ru":"Внезапно в здании сработала сигнализация.","vi":"Đột nhiên chuông báo động trong tòa nhà vang lên.","fa":"ناگهان زنگ در ساختمان به صدا درآمد."},{"de":"Bei Feuer sollten Sie sofort Alarm schlagen.","en":"In case of fire, you should raise the alarm immediately.","ru":"В случае пожара нужно немедленно поднять тревогу.","vi":"Nếu có hỏa hoạn, bạn nên phát ra âm thanh báo động ngay lập tức.","fa":"در صورت وقوع آتش سوزی باید فوراً زنگ خطر را به صدا در آورید."}]},{"word":"die Algebra","en":"algebra","ru":"алгебра","vi":"đại số","fa":"جبر","examples":[{"de":"In der Algebra rechnet man oft mit Buchstaben statt mit Zahlen.","en":"In algebra you often calculate with letters instead of numbers.","ru":"В алгебре часто оперируют буквами вместо чисел.","vi":"Trong đại số bạn thường tính toán bằng chữ cái thay vì số.","fa":"در جبر شما اغلب با حروف به جای اعداد محاسبه می کنید."},{"de":"In der Schule fiel ihr die Algebra schwerer als die Geometrie.","en":"At school she found algebra harder than geometry.","ru":"В школе алгебра давалась ей труднее, чем геометрия.","vi":"Ở trường cô thấy đại số khó hơn hình học.","fa":"در مدرسه جبر را دشوارتر از هندسه یافت."},{"de":"Mit etwas Algebra lässt sich diese Gleichung leicht lösen.","en":"With a little algebra, this equation is easy to solve.","ru":"С помощью небольшой алгебры это уравнение легко решается.","vi":"Với một chút đại số, phương trình này có thể được giải dễ dàng.","fa":"با کمی جبر می توان این معادله را به راحتی حل کرد."}]},{"word":"der Alkohol","en":"alcohol","ru":"алкоголь","vi":"rượu","fa":"الکل","examples":[{"de":"Er trinkt seit Jahren keinen Alkohol mehr.","en":"He hasn't drunk alcohol for years.","ru":"Он уже много лет не пьёт алкоголь.","vi":"Anh ấy đã không uống rượu trong nhiều năm rồi.","fa":"او سالها الکل ننوشیده است."},{"de":"Alkohol am Steuer ist in Deutschland verboten.","en":"Alcohol at the wheel is prohibited in Germany.","ru":"Употребление алкоголя за рулём в Германии запрещено.","vi":"Alkohol am Steuer ist ở Deutschland verboten.","fa":"مشروب الکلی و رانندگی در آلمان ممنوع است."}]},{"word":"all-","en":"all-, every- (prefix)","ru":"все-, каждый- (приставка)","vi":"tất cả-","fa":"همه-","examples":[{"de":"Kleine Streitigkeiten sind in einer Familie ganz alltäglich.","en":"Small quarrels are quite common (everyday) in a family.","ru":"Небольшие ссоры в семье — обычное, повседневное дело.","vi":"Những tranh cãi nhỏ là chuyện thường tình trong một gia đình.","fa":"دعواهای کوچک در یک خانواده رایج است."},{"de":"Ein Stau am Morgen ist in dieser Stadt alltäglich geworden.","en":"A traffic jam in the morning has become an everyday occurrence in this city.","ru":"Пробка по утрам стала обычным явлением в этом городе.","vi":"Ùn tắc giao thông buổi sáng đã trở nên phổ biến ở thành phố này.","fa":"ترافیک صبحگاهی در این شهر عادی شده است."}]},{"word":"allein","en":"alone","ru":"один, в одиночестве","vi":"một mình","fa":"به تنهایی","examples":[{"de":"Sie wohnt allein in einer kleinen Wohnung.","en":"She lives alone in a small apartment.","ru":"Она живёт одна в маленькой квартире.","vi":"Cô sống một mình trong một căn hộ nhỏ.","fa":"او به تنهایی در یک آپارتمان کوچک زندگی می کند."},{"de":"Ich möchte heute Abend lieber allein sein.","en":"I would rather be alone this evening.","ru":"Сегодня вечером я предпочёл бы побыть один.","vi":"Tôi thà ở một mình tối nay.","fa":"ترجیح میدم امشب تنها باشم"}]},{"word":"aller-","en":"-est of all (superlative prefix)","ru":"самый- (усилительная приставка превосходной степени)","vi":"tất cả-","fa":"همه-","examples":[{"de":"Das war der allerbeste Kuchen, den ich je gegessen habe.","en":"That was the very best cake I have ever eaten.","ru":"Это был самый лучший торт, который я когда-либо ел.","vi":"Đây là chiếc bánh ngon nhất mà tôi từng ăn.","fa":"این بهترین کیکی بود که تا به حال خوردم."},{"de":"Er kam als Allerletzter ins Ziel.","en":"He came in as the very last one at the finish line.","ru":"Он пришёл к финишу самым последним.","vi":"Anh ấy đã hoàn thành cuối cùng.","fa":"او آخر شد."}]},{"word":"allerbest","en":"very best, best of all","ru":"самый лучший, лучший из всех","vi":"rất tốt nhất","fa":"بسیار بهترین","examples":[{"de":"Du bist mein allerbester Freund.","en":"You are my very best friend.","ru":"Ты моя самая лучшая подруга.","vi":"Bạn là người bạn tốt nhất của tôi.","fa":"تو بهترین دوست من هستی"},{"de":"Das ist die allerbeste Lösung.","en":"That is the very best solution.","ru":"Это самое лучшее решение.","vi":"Đây là giải pháp tốt nhất.","fa":"این بهترین راه حل است."},{"de":"Ich wünsche dir das Allerbeste zum Geburtstag.","en":"I wish you all the very best for your birthday.","ru":"Желаю тебе всего самого наилучшего в день рождения.","vi":"Tôi chúc bạn sinh nhật tốt nhất.","fa":"بهترین تولد را برای شما آرزو می کنم."}]},{"word":"allerdings","en":"however, though","ru":"однако, впрочем","vi":"tuy nhiên","fa":"با این حال","examples":[{"de":"Das Restaurant ist gut, allerdings auch ziemlich teuer.","en":"The restaurant is good, however also quite expensive.","ru":"Ресторан хороший, однако довольно дорогой.","vi":"Nhà hàng ngon nhưng cũng khá đắt.","fa":"رستوران خوب است، اما بسیار گران است."},{"de":"Ich komme gerne mit, allerdings erst nach der Arbeit.","en":"I would love to come along, though only after work.","ru":"Я с удовольствием приду, однако только после работы.","vi":"Tôi rất vui được đi cùng bạn, nhưng chỉ sau giờ làm việc thôi.","fa":"خوشحال می شوم با شما بیایم، اما فقط بعد از کار."}]},{"word":"allergisch","en":"allergic","ru":"аллергический, страдающий аллергией","vi":"dị ứng","fa":"آلرژیک","examples":[{"de":"Ich bin allergisch gegen Katzen.","en":"I'm allergic to cats.","ru":"У меня аллергия на кошек.","vi":"Tôi bị dị ứng với mèo.","fa":"من به گربه ها حساسیت دارم."},{"de":"Sie reagiert allergisch auf bestimmte Lebensmittel.","en":"She reacts allergically to certain foods.","ru":"Она даёт аллергическую реакцию на некоторые продукты.","vi":"Cô ấy bị dị ứng với một số loại thực phẩm.","fa":"او به برخی غذاها حساسیت دارد."},{"de":"Bist du gegen Pollen allergisch?","en":"Are you allergic to pollen?","ru":"У тебя аллергия на пыльцу?","vi":"Bạn có bị dị ứng với phấn hoa không?","fa":"آیا به گرده گل آلرژی دارید؟"}]},{"word":"allerschönst","en":"most beautiful of all, very loveliest","ru":"самый красивый из всех, красивейший","vi":"đẹp nhất","fa":"زیباترین","examples":[{"de":"Das war der allerschönste Tag meines Lebens.","en":"That was the most beautiful day of my life.","ru":"Это был самый прекрасный день в моей жизни.","vi":"Đó là ngày đẹp nhất trong cuộc đời tôi.","fa":"آن روز زیباترین روز زندگی من بود."},{"de":"Sie trug das allerschönste Kleid auf der Feier.","en":"She wore the most beautiful dress at the party.","ru":"На празднике она была в самом красивом платье.","vi":"Cô mặc chiếc váy đẹp nhất trong bữa tiệc.","fa":"او زیباترین لباس را در مهمانی پوشید."},{"de":"Wir haben den allerschönsten Platz am Strand bekommen.","en":"We got the very loveliest spot on the beach.","ru":"Нам досталось самое красивое место на пляже.","vi":"Chúng tôi có được vị trí đẹp nhất trên bãi biển.","fa":"ما زیباترین نقطه ساحل را به دست آوردیم."}]},{"word":"alles in Butter","en":"everything's fine (colloquial)","ru":"всё в порядке (разг.)","vi":"mọi thứ đều ổn","fa":"همه چیز خوب است","examples":[{"de":"Keine Sorge, bei uns ist alles in Butter.","en":"Don't worry, everything's fine with us.","ru":"Не переживай, у нас всё в порядке.","vi":"Đừng lo lắng, mọi thứ với chúng tôi đều ổn.","fa":"نگران نباش، همه چیز با ما خوب است."}]},{"word":"allgemein","en":"general","ru":"общий, всеобщий","vi":"chung","fa":"عمومی","examples":[{"de":"Das ist eine allgemeine Regel, die für alle gilt.","en":"That is a general rule that applies to everyone.","ru":"Это общее правило, которое действует для всех.","vi":"Đây là nguyên tắc chung áp dụng cho tất cả mọi người.","fa":"این یک قانون کلی است که برای همه صدق می کند."},{"de":"Im Allgemeinen bin ich mit meinem Job zufrieden.","en":"In general, I am satisfied with my job.","ru":"В общем, я доволен своей работой.","vi":"Nói chung tôi hài lòng với công việc của mình.","fa":"در کل از شغلم راضی هستم."}]},{"word":"allmählich","en":"gradually, slowly","ru":"постепенный, постепенно; понемногу","vi":"dần dần","fa":"به تدریج","examples":[{"de":"Allmählich wird es draußen wärmer.","en":"It is gradually getting warmer outside.","ru":"Постепенно на улице становится теплее.","vi":"Bên ngoài đang dần ấm lên.","fa":"بیرون کم کم گرمتر می شود."},{"de":"Ich verstehe allmählich, wie das funktioniert.","en":"I am gradually understanding how this works.","ru":"Я постепенно понимаю, как это работает.","vi":"Tôi bắt đầu hiểu cách thức hoạt động của nó.","fa":"من شروع به درک نحوه عملکرد این کار کردم."},{"de":"Die Schmerzen lassen allmählich nach.","en":"The pain is gradually easing.","ru":"Боль постепенно утихает.","vi":"Cơn đau giảm dần.","fa":"درد به تدریج فروکش می کند."}]},{"word":"der Alltag","en":"everyday life, routine","ru":"повседневная жизнь, будни","vi":"cuộc sống hàng ngày","fa":"زندگی روزمره","examples":[{"de":"Nach dem Urlaub beginnt wieder der graue Alltag.","en":"After the vacation, the gray everyday routine begins again.","ru":"После отпуска снова начинаются серые будни.","vi":"Sau kỳ nghỉ, cuộc sống xám xịt thường ngày lại bắt đầu.","fa":"پس از تعطیلات، زندگی روزمره خاکستری دوباره آغاز می شود."},{"de":"Im Alltag habe ich kaum Zeit zum Lesen.","en":"In everyday life I hardly have time to read.","ru":"В повседневной жизни у меня почти нет времени на чтение.","vi":"Tôi hầu như không có thời gian để đọc trong cuộc sống hàng ngày.","fa":"در زندگی روزمره به سختی وقت برای مطالعه دارم."}]},{"word":"alltäglich","en":"everyday, ordinary","ru":"повседневный, обыденный","vi":"hàng ngày","fa":"هر روز","examples":[{"de":"Das sind ganz alltägliche Probleme.","en":"These are quite everyday problems.","ru":"Это совершенно обыденные проблемы.","vi":"Đây là những vấn đề hàng ngày.","fa":"اینها مشکلات روزمره است."},{"de":"Für sie ist die lange Fahrt etwas Alltägliches.","en":"For her the long journey is something ordinary.","ru":"Для неё долгая дорога — дело обыденное.","vi":"Đối với họ, cuộc hành trình dài là điều gì đó diễn ra hàng ngày.","fa":"برای آنها سفر طولانی امری روزمره است."},{"de":"Solche Gespräche gehören zu meinen alltäglichen Pflichten.","en":"Such conversations are part of my everyday duties.","ru":"Такие разговоры входят в мои повседневные обязанности.","vi":"Những cuộc trò chuyện như vậy là một phần công việc hàng ngày của tôi.","fa":"چنین گفتگوهایی بخشی از وظایف روزمره من است."}]},{"word":"das Alphabet","en":"alphabet","ru":"алфавит","vi":"bảng chữ cái","fa":"الفبا","examples":[{"de":"Das deutsche Alphabet hat 26 Buchstaben und einige Sonderzeichen.","en":"The German alphabet has 26 letters and some special characters.","ru":"В немецком алфавите 26 букв и несколько специальных знаков.","vi":"Bảng chữ cái tiếng Đức có 26 chữ cái và một số ký tự đặc biệt.","fa":"الفبای آلمانی دارای 26 حرف و چند کاراکتر خاص است."},{"de":"Die Kinder lernen im ersten Schuljahr das Alphabet.","en":"The children learn the alphabet in their first year of school.","ru":"Дети учат алфавит в первом классе школы.","vi":"Trẻ em học bảng chữ cái trong năm học đầu tiên.","fa":"بچه ها در سال اول تحصیلی الفبا را یاد می گیرند."}]},{"word":"als","en":"than; when; as","ru":"чем; когда; как","vi":"như","fa":"به عنوان","examples":[{"de":"Sie ist größer als ihr Bruder.","en":"She is taller than her brother.","ru":"Она выше своего брата.","vi":"Cô ấy cao hơn anh trai cô ấy.","fa":"او از برادرش بلندتر است."},{"de":"Als ich klein war, wohnte ich auf dem Land.","en":"When I was little, I lived in the countryside.","ru":"Когда я был маленьким, я жил в деревне.","vi":"Hồi nhỏ tôi sống ở quê.","fa":"وقتی کوچک بودم، در کشور زندگی می کردم."}]},{"word":"Als ich jünger war, …","en":"When I was younger, … (recounting the past)","ru":"Когда я был моложе, … (рассказ о прошлом)","vi":"Khi tôi còn trẻ,…","fa":"وقتی جوانتر بودم،…","examples":[{"de":"Als ich jünger war, habe ich viel Fußball gespielt.","en":"When I was younger, I played a lot of football.","ru":"Когда я был моложе, я много играл в футбол.","vi":"Khi tôi còn trẻ, tôi đã chơi rất nhiều bóng đá.","fa":"وقتی جوانتر بودم، خیلی فوتبال بازی می کردم."}]},{"word":"also","en":"so, therefore","ru":"итак, следовательно","vi":"vậy","fa":"بنابراین","examples":[{"de":"Es regnet, also nehme ich einen Regenschirm mit.","en":"It's raining, so I'll take an umbrella.","ru":"Идёт дождь, поэтому я возьму зонт.","vi":"Trời đang mưa nên tôi mang theo ô.","fa":"باران می بارد، پس چتر برمی دارم."},{"de":"Also, dann sehen wir uns morgen um neun Uhr.","en":"So, then we'll see each other tomorrow at nine o'clock.","ru":"Итак, увидимся завтра в девять часов.","vi":"Vâng, hẹn gặp bạn vào lúc 9 giờ ngày mai.","fa":"خب فردا ساعت نه میبینمت"}]},{"word":"alt","en":"old","ru":"старый","vi":"cũ","fa":"قدیمی","examples":[{"de":"Mein Großvater ist schon 85 Jahre alt.","en":"My grandfather is already 85 years old.","ru":"Моему дедушке уже 85 лет.","vi":"Ông tôi đã 85 tuổi rồi.","fa":"پدربزرگ من در حال حاضر 85 سال دارد."},{"de":"Wir wohnen in einem alten Haus aus dem 19. Jahrhundert.","en":"We live in an old house from the 19th century.","ru":"Мы живём в старом доме XIX века.","vi":"Chúng tôi sống trong một ngôi nhà cổ từ thế kỷ 19.","fa":"ما در خانه ای قدیمی از قرن نوزدهم زندگی می کنیم."}]},{"word":"das Altenheim","en":"old people's home, care home","ru":"дом престарелых","vi":"nhà hưu trí","fa":"خانه سالمندان","examples":[{"de":"Meine Großmutter lebt seit einem Jahr im Altenheim.","en":"My grandmother has been living in a care home for a year.","ru":"Моя бабушка уже год живёт в доме престарелых.","vi":"Bà tôi đã sống ở viện dưỡng lão được một năm.","fa":"مادربزرگ من یک سال است که در خانه سالمندان زندگی می کند."},{"de":"Im Altenheim arbeiten viele freundliche Pflegekräfte.","en":"Many friendly carers work in the care home.","ru":"В доме престарелых работает много приветливых сиделок.","vi":"Nhiều nhân viên điều dưỡng thân thiện làm việc tại viện dưỡng lão.","fa":"بسیاری از کارکنان پرستاری مهربان در خانه سالمندان کار می کنند."},{"de":"Wir besuchen das Altenheim jeden Sonntag.","en":"We visit the old people's home every Sunday.","ru":"Мы навещаем дом престарелых каждое воскресенье.","vi":"Chúng tôi đến thăm viện dưỡng lão vào mỗi Chủ Nhật.","fa":"ما هر یکشنبه به خانه سالمندان سر می زنیم."}]},{"word":"das Alter","en":"age","ru":"возраст","vi":"tuổi","fa":"سن","examples":[{"de":"In welchem Alter hast du das Schwimmen gelernt?","en":"At what age did you learn to swim?","ru":"В каком возрасте ты научился плавать?","vi":"Bạn học bơi lúc bao nhiêu tuổi?","fa":"از چه سنی شنا یاد گرفتی؟"},{"de":"Im Alter reist sie gerne durch Europa.","en":"In her old age, she likes to travel through Europe.","ru":"В пожилом возрасте она любит путешествовать по Европе.","vi":"Ở tuổi già, bà thích đi du lịch khắp châu Âu.","fa":"در دوران پیری از سفر در اروپا لذت می برد."}]},{"word":"alternativ","en":"alternative(ly)","ru":"альтернативный, альтернативно","vi":"cách khác","fa":"جایگزین","examples":[{"de":"Alternativ können wir auch mit dem Zug fahren.","en":"Alternatively, we could also go by train.","ru":"В качестве альтернативы мы можем поехать на поезде.","vi":"Ngoài ra, chúng ta cũng có thể đi tàu.","fa":"در غیر این صورت، می توانیم با قطار نیز سوار شویم."},{"de":"Immer mehr Menschen nutzen alternative Energiequellen.","en":"More and more people use alternative energy sources.","ru":"Всё больше людей используют альтернативные источники энергии.","vi":"Ngày càng có nhiều người sử dụng các nguồn năng lượng thay thế.","fa":"افراد بیشتری از منابع انرژی جایگزین استفاده می کنند."}]},{"word":"die Alternative","en":"alternative","ru":"альтернатива, другой вариант","vi":"sự thay thế","fa":"جایگزین","examples":[{"de":"Gibt es eine günstigere Alternative?","en":"Is there a cheaper alternative?","ru":"Есть ли вариант подешевле?","vi":"Có một sự thay thế rẻ hơn?","fa":"آیا جایگزین ارزان تری وجود دارد؟"},{"de":"Das Fahrrad ist eine gute Alternative zum Auto.","en":"The bicycle is a good alternative to the car.","ru":"Велосипед — хорошая альтернатива автомобилю.","vi":"Xe đạp là một sự thay thế tốt cho ô tô.","fa":"دوچرخه جایگزین خوبی برای ماشین است."},{"de":"Wir hatten leider keine andere Alternative.","en":"Unfortunately we had no other alternative.","ru":"У нас, к сожалению, не было другого выбора.","vi":"Thật không may, chúng tôi không có lựa chọn nào khác.","fa":"متاسفانه ما جایگزین دیگری نداشتیم."}]},{"word":"das Altersheim","en":"old people's home, care home","ru":"дом престарелых","vi":"nhà hưu trí","fa":"خانه سالمندان","examples":[{"de":"Mein Großvater fühlt sich im Altersheim sehr wohl.","en":"My grandfather feels very comfortable in the care home.","ru":"Мой дедушка чувствует себя в доме престарелых очень хорошо.","vi":"Ông tôi cảm thấy rất thoải mái khi ở nhà hưu trí.","fa":"پدربزرگ من در خانه سالمندان احساس راحتی می کند."},{"de":"Das Altersheim liegt ruhig am Rand der Stadt.","en":"The care home is situated quietly on the edge of town.","ru":"Дом престарелых расположен тихо, на краю города.","vi":"Nhà hưu trí nằm lặng lẽ ở ngoại ô thành phố.","fa":"خانه سالمندان در فضایی آرام در حومه شهر واقع شده است."},{"de":"Im Altersheim gibt es jeden Tag gemeinsame Mahlzeiten.","en":"In the care home there are communal meals every day.","ru":"В доме престарелых каждый день бывают совместные трапезы.","vi":"Có những bữa ăn chung hàng ngày tại viện dưỡng lão.","fa":"در خانه سالمندان هر روز وعده های غذایی اشتراکی وجود دارد."}]},{"word":"Am liebsten würde ich …","en":"Most of all I'd like to … (strong preference)","ru":"Больше всего мне хотелось бы … (сильное предпочтение)","vi":"Trên hết tôi muốn…","fa":"بیشتر از همه دوست دارم…","examples":[{"de":"Am liebsten würde ich sofort losfahren.","en":"Most of all I'd like to set off right away.","ru":"Больше всего мне хотелось бы сразу отправиться в путь.","vi":"Tôi rất muốn khởi hành ngay lập tức.","fa":"دوست دارم فوراً راه بیفتم."}]},{"word":"die Ampel","en":"traffic light","ru":"светофор","vi":"đèn giao thông","fa":"چراغ های راهنمایی","examples":[{"de":"Bitte warte, bis die Ampel grün wird.","en":"Please wait until the traffic light turns green.","ru":"Пожалуйста, подожди, пока светофор станет зелёным.","vi":"Vui lòng đợi cho đến khi đèn giao thông chuyển sang màu xanh.","fa":"لطفا صبر کنید تا چراغ راهنمایی سبز شود."},{"de":"An der Ampel ist gerade ein Unfall passiert.","en":"An accident just happened at the traffic light.","ru":"У светофора только что произошла авария.","vi":"Một vụ tai nạn vừa xảy ra ở đèn giao thông.","fa":"تصادف در چراغ راهنمایی اتفاق افتاد."}]},{"word":"das Amt","en":"official office, authority","ru":"ведомство, учреждение","vi":"văn phòng","fa":"دفتر","examples":[{"de":"Für den neuen Pass müssen Sie zum Amt gehen.","en":"For the new passport, you have to go to the office (authority).","ru":"Для получения нового паспорта нужно пойти в учреждение.","vi":"Bạn phải đến văn phòng để lấy hộ chiếu mới.","fa":"برای گرفتن پاسپورت جدید باید به اداره مراجعه کنید."},{"de":"Das Amt für Ausländerfragen befindet sich im Stadtzentrum.","en":"The office for foreigners' affairs is located in the city center.","ru":"Управление по делам иностранцев находится в центре города.","vi":"Văn phòng đối ngoại nằm ở trung tâm thành phố.","fa":"دفتر امور اتباع خارجی در مرکز شهر قرار دارد."}]},{"word":"amüsieren","en":"to amuse; (reflexive) to have a good time, to enjoy oneself","ru":"развлекать; (возвр.) развлекаться, весело проводить время","vi":"thích thú","fa":"سرگرم کردن","examples":[{"de":"Wir haben uns auf der Party gut amüsiert.","en":"We had a good time at the party.","ru":"Мы весело провели время на празднике.","vi":"Chúng tôi đã có khoảng thời gian vui vẻ tại bữa tiệc.","fa":"در مهمانی به ما خوش گذشت."},{"de":"Die Kinder amüsieren sich im Garten.","en":"The children are enjoying themselves in the garden.","ru":"Дети развлекаются в саду.","vi":"Bọn trẻ đang vui chơi trong vườn.","fa":"بچه ها در باغ خوش می گذرانند."},{"de":"Seine Geschichte hat alle sehr amüsiert.","en":"His story amused everyone a lot.","ru":"Его история всех очень развеселила.","vi":"Câu chuyện của anh khiến mọi người thích thú.","fa":"داستان او همه را سرگرم کرد."}]},{"word":"an","en":"at, on","ru":"у, на, в (предлог)","vi":"trên","fa":"در","examples":[{"de":"Das Bild hängt an der Wand.","en":"The picture is hanging on the wall.","ru":"Картина висит на стене.","vi":"Bức tranh treo trên tường.","fa":"عکس روی دیوار آویزان است."},{"de":"Wir treffen uns am Freitag an der Bushaltestelle.","en":"We are meeting on Friday at the bus stop.","ru":"Мы встречаемся в пятницу у автобусной остановки.","vi":"Chúng ta sẽ gặp nhau ở trạm xe buýt vào thứ Sáu.","fa":"جمعه در ایستگاه اتوبوس همدیگر را می بینیم."}]},{"word":"die Analyse","en":"analysis","ru":"анализ","vi":"sự phân tích","fa":"تجزیه و تحلیل","examples":[{"de":"Die Analyse der Daten dauerte mehrere Tage.","en":"The analysis of the data took several days.","ru":"Анализ данных занял несколько дней.","vi":"Việc phân tích dữ liệu mất vài ngày.","fa":"تجزیه و تحلیل داده ها چند روز طول کشید."},{"de":"Für die Analyse brauchen wir saubere Daten.","en":"For the analysis we need clean data.","ru":"Для анализа нам нужны чистые данные.","vi":"Chúng tôi cần dữ liệu sạch để phân tích.","fa":"ما برای تجزیه و تحلیل به داده های تمیز نیاز داریم."},{"de":"Seine Analyse zeigte einen klaren Trend.","en":"His analysis showed a clear trend.","ru":"Его анализ показал чёткий тренд.","vi":"Phân tích của ông cho thấy một xu hướng rõ ràng.","fa":"تحلیل او روند روشنی را نشان داد."}]},{"word":"analysieren","en":"to analyze","ru":"анализировать","vi":"phân tích","fa":"تجزیه و تحلیل کنید","examples":[{"de":"Der Lehrer bat uns, das Gedicht genau zu analysieren.","en":"The teacher asked us to analyze the poem carefully.","ru":"Учитель попросил нас внимательно проанализировать стихотворение.","vi":"Giáo viên yêu cầu chúng tôi phân tích bài thơ một cách cẩn thận.","fa":"معلم از ما خواست که شعر را با دقت تجزیه و تحلیل کنیم."},{"de":"Der Arzt analysiert zuerst die Blutwerte des Patienten.","en":"The doctor first analyzes the patient's blood values.","ru":"Врач сначала анализирует показатели крови пациента.","vi":"Đầu tiên bác sĩ sẽ phân tích giá trị máu của bệnh nhân.","fa":"پزشک ابتدا مقادیر خونی بیمار را تجزیه و تحلیل می کند."}]},{"word":"anbauen","en":"to grow/cultivate (crops); to build on, to add (an extension)","ru":"выращивать (культуры); пристраивать (к зданию)","vi":"phát triển","fa":"رشد کنند","examples":[{"de":"In dieser Region baut man vor allem Wein an.","en":"In this region they mainly grow wine.","ru":"В этом регионе выращивают в основном виноград.","vi":"Rượu vang chủ yếu được trồng ở vùng này.","fa":"شراب عمدتاً در این منطقه کشت می شود."},{"de":"Wir bauen im Garten Gemüse an.","en":"We grow vegetables in the garden.","ru":"Мы выращиваем овощи в саду.","vi":"Chúng tôi trồng rau trong vườn.","fa":"ما در باغ سبزی می کاریم."},{"de":"Sie haben ein neues Zimmer an das Haus angebaut.","en":"They built a new room onto the house.","ru":"Они пристроили к дому новую комнату.","vi":"Họ đã thêm một căn phòng mới vào nhà.","fa":"آنها یک اتاق جدید به خانه اضافه کردند."}]},{"word":"anbieten","en":"to offer","ru":"предлагать","vi":"đề nghị","fa":"پیشنهاد","examples":[{"de":"Das Hotel bietet seinen Gästen kostenloses WLAN an.","en":"The hotel offers its guests free WiFi.","ru":"Отель предлагает своим гостям бесплатный Wi-Fi.","vi":"Khách sạn cung cấp cho khách Wi-Fi miễn phí.","fa":"این هتل به مهمانان خود وای فای رایگان ارائه می دهد."},{"de":"Kann ich Ihnen etwas zu trinken anbieten?","en":"Can I offer you something to drink?","ru":"Могу я предложить вам что-нибудь выпить?","vi":"Tôi có thể mời bạn thứ gì đó để uống không?","fa":"آیا می توانم به شما چیزی برای نوشیدن پیشنهاد کنم؟"}]},{"word":"der Anbieter","en":"provider, supplier","ru":"поставщик, провайдер","vi":"nhà cung cấp","fa":"ارائه دهنده","examples":[{"de":"Ich habe den Anbieter für mein Handy gewechselt.","en":"I switched the provider for my mobile phone.","ru":"Я сменил оператора для своего телефона.","vi":"Tôi đã thay đổi nhà cung cấp cho điện thoại di động của mình.","fa":"ارائه دهنده تلفن همراهم را عوض کردم."},{"de":"Dieser Anbieter hat die günstigsten Preise.","en":"This provider has the cheapest prices.","ru":"У этого поставщика самые выгодные цены.","vi":"Nhà cung cấp này có giá rẻ nhất.","fa":"این ارائه دهنده ارزان ترین قیمت ها را دارد."},{"de":"Es gibt viele Anbieter für Internetverträge.","en":"There are many providers for internet contracts.","ru":"Есть много провайдеров интернет-услуг.","vi":"Có rất nhiều nhà cung cấp hợp đồng internet.","fa":"ارائه دهندگان زیادی برای قراردادهای اینترنتی وجود دارد."}]},{"word":"ander-","en":"other, different","ru":"другой, иной","vi":"khác-","fa":"دیگر-","examples":[{"de":"Ich hätte gern einen anderen Platz am Fenster.","en":"I would like a different seat by the window.","ru":"Я хотел бы другое место у окна.","vi":"Tôi muốn một chỗ ngồi khác cạnh cửa sổ.","fa":"من یک صندلی دیگر کنار پنجره می خواهم."},{"de":"Das ist eine ganz andere Angelegenheit.","en":"That is a completely different matter.","ru":"Это совсем другое дело.","vi":"Đó là một vấn đề hoàn toàn khác.","fa":"این یک موضوع کاملا متفاوت است."}]},{"word":"andererseits","en":"on the other hand","ru":"с другой стороны","vi":"mặt khác","fa":"از سوی دیگر","examples":[{"de":"Einerseits möchte ich reisen, andererseits fehlt mir das Geld.","en":"On one hand I want to travel, on the other hand I lack the money.","ru":"С одной стороны, я хочу путешествовать, с другой — у меня нет денег.","vi":"Một mặt tôi muốn đi du lịch, mặt khác tôi không có tiền.","fa":"از یک طرف می خواهم سفر کنم، از طرف دیگر پول ندارم."},{"de":"Er ist streng, andererseits aber auch sehr gerecht.","en":"He is strict, but on the other hand also very fair.","ru":"Он строгий, но, с другой стороны, очень справедливый.","vi":"Anh ấy nghiêm khắc nhưng mặt khác cũng rất công bằng.","fa":"او سختگیر است، اما از طرف دیگر بسیار منصف است."}]},{"word":"ändern","en":"to change","ru":"менять, изменять","vi":"thay đổi","fa":"تغییر دهید","examples":[{"de":"Ich möchte meinen Termin auf nächste Woche ändern.","en":"I would like to change my appointment to next week.","ru":"Я хотел бы перенести встречу на следующую неделю.","vi":"Tôi muốn đổi cuộc hẹn sang tuần sau.","fa":"من می خواهم قرارم را به هفته آینده تغییر دهم."},{"de":"Das Wetter hat sich plötzlich geändert.","en":"The weather changed suddenly.","ru":"Погода внезапно изменилась.","vi":"Thời tiết đột nhiên thay đổi.","fa":"هوا ناگهان تغییر کرد."}]},{"word":"anders","en":"differently, otherwise","ru":"по-другому, иначе","vi":"khác nhau","fa":"متفاوت است","examples":[{"de":"Diesmal machen wir es anders als sonst.","en":"This time we're doing it differently than usual.","ru":"На этот раз мы сделаем это иначе, чем обычно.","vi":"Lần này chúng tôi làm việc đó khác với thường lệ.","fa":"این بار ما آن را متفاوت از حد معمول انجام می دهیم."},{"de":"Sie denkt einfach anders als die meisten Leute.","en":"She simply thinks differently than most people.","ru":"Она просто думает иначе, чем большинство людей.","vi":"Cô ấy chỉ nghĩ khác với hầu hết mọi người.","fa":"او فقط متفاوت از بسیاری از مردم فکر می کند."}]},{"word":"anderseits","en":"on the other hand (variant of andererseits)","ru":"с другой стороны (вариант andererseits)","vi":"mặt khác","fa":"از سوی دیگر","examples":[{"de":"Einerseits ja, anderseits nein.","en":"On the one hand yes, on the other hand no.","ru":"С одной стороны — да, с другой — нет.","vi":"Một mặt có, mặt khác không.","fa":"از یک طرف بله، از طرف دیگر خیر."},{"de":"Das Auto ist teuer, anderseits sehr sparsam.","en":"The car is expensive, on the other hand very economical.","ru":"Машина дорогая, зато очень экономичная.","vi":"Chiếc xe đắt tiền, nhưng mặt khác nó rất tiết kiệm.","fa":"ماشین گرونه ولی از طرفی خیلی به صرفه هست."},{"de":"Anderseits könnte man auch zu Hause bleiben.","en":"On the other hand, one could also stay at home.","ru":"С другой стороны, можно было бы и остаться дома.","vi":"Mặt khác, bạn cũng có thể ở nhà.","fa":"از طرف دیگر، شما همچنین می توانید در خانه بمانید."}]},{"word":"die Änderung","en":"change, alteration, amendment","ru":"изменение, поправка","vi":"sự thay đổi","fa":"تغییر","examples":[{"de":"Es gab eine kleine Änderung im Programm.","en":"There was a small change to the programme.","ru":"В программе было небольшое изменение.","vi":"Có một thay đổi nhỏ trong chương trình.","fa":"یک تغییر کوچک در برنامه ایجاد شد."},{"de":"Die Änderung des Vertrags muss schriftlich erfolgen.","en":"The change to the contract must be made in writing.","ru":"Изменение договора должно оформляться письменно.","vi":"Việc thay đổi hợp đồng phải được thực hiện bằng văn bản.","fa":"تغییر در قرارداد باید به صورت کتبی انجام شود."},{"de":"Wir müssen einige Änderungen vornehmen.","en":"We have to make a few changes.","ru":"Нам нужно внести несколько изменений.","vi":"Chúng ta cần thực hiện một số thay đổi.","fa":"ما باید تغییراتی ایجاد کنیم."}]},{"word":"andrerseits","en":"on the other hand (variant of andererseits)","ru":"с другой стороны (вариант andererseits)","vi":"mặt khác","fa":"از سوی دیگر","examples":[{"de":"Einerseits will ich sparen, andrerseits brauche ich ein neues Handy.","en":"On the one hand I want to save, on the other hand I need a new phone.","ru":"С одной стороны, я хочу копить, с другой — мне нужен новый телефон.","vi":"Một mặt tôi muốn tiết kiệm tiền, mặt khác tôi cần một chiếc điện thoại di động mới.","fa":"از یک طرف می خواهم در پول خود صرفه جویی کنم، از طرف دیگر به یک تلفن همراه جدید نیاز دارم."},{"de":"Es ist riskant, andrerseits eine große Chance.","en":"It's risky, on the other hand a great opportunity.","ru":"Это рискованно, но с другой стороны — прекрасная возможность.","vi":"Đó là rủi ro, nhưng mặt khác lại là một cơ hội tuyệt vời.","fa":"ریسکی است، اما از طرف دیگر یک فرصت عالی."},{"de":"Andrerseits sollten wir nicht zu lange warten.","en":"On the other hand, we shouldn't wait too long.","ru":"С другой стороны, не стоит ждать слишком долго.","vi":"Mặt khác, chúng ta không nên chờ đợi quá lâu.","fa":"از طرفی نباید زیاد منتظر بمانیم."}]},{"word":"anerkennen","en":"to acknowledge, to recognize","ru":"признавать","vi":"thừa nhận","fa":"تصدیق کند","examples":[{"de":"Der Chef hat ihre gute Arbeit endlich anerkannt.","en":"The boss finally acknowledged her good work.","ru":"Начальник наконец признал её хорошую работу.","vi":"Ông chủ cuối cùng đã công nhận việc làm tốt của cô.","fa":"رئیس بالاخره کار خوب او را تشخیص داد."},{"de":"Dieser Abschluss wird in vielen Ländern anerkannt.","en":"This degree is recognized in many countries.","ru":"Этот диплом признаётся во многих странах.","vi":"Bằng cấp này được công nhận ở nhiều nước.","fa":"این مدرک در بسیاری از کشورها به رسمیت شناخته شده است."}]},{"word":"die Anerkennung","en":"recognition; appreciation","ru":"признание, уважение","vi":"sự công nhận","fa":"شناخت","examples":[{"de":"Jeder Mensch braucht ein wenig Anerkennung.","en":"Every person needs a little recognition.","ru":"Каждому человеку нужно хоть немного признания.","vi":"Mọi người đều cần một chút sự công nhận.","fa":"همه به کمی شناخت نیاز دارند."},{"de":"Ihre Arbeit fand große gesellschaftliche Anerkennung.","en":"Her work found great social recognition.","ru":"Её работа получила большое общественное признание.","vi":"Công việc của họ đã nhận được sự công nhận xã hội lớn.","fa":"کار آنها به رسمیت شناخته شده اجتماعی زیادی دریافت کرد."},{"de":"Ohne Anerkennung verlieren viele die Motivation.","en":"Without recognition many people lose motivation.","ru":"Без признания многие теряют мотивацию.","vi":"Không có sự công nhận, nhiều người mất động lực.","fa":"بدون شناخت، بسیاری انگیزه خود را از دست می دهند."}]},{"word":"anfangen","en":"to begin, to start","ru":"начинать","vi":"bắt đầu","fa":"شروع کنید","examples":[{"de":"Der Film fängt um 20 Uhr an.","en":"The movie starts at 8 p.m.","ru":"Фильм начинается в 20:00.","vi":"Phim bắt đầu lúc 8 giờ tối.","fa":"فیلم ساعت 20 شروع می شود."},{"de":"Ich möchte nächsten Monat mit einer neuen Sprache anfangen.","en":"I would like to start with a new language next month.","ru":"Я хочу начать изучать новый язык в следующем месяце.","vi":"Tôi muốn bắt đầu với một ngôn ngữ mới vào tháng tới.","fa":"من می خواهم ماه آینده با یک زبان جدید شروع کنم."}]},{"word":"anfangs","en":"at first, initially","ru":"сначала, поначалу","vi":"ban đầu","fa":"در ابتدا","examples":[{"de":"Anfangs war die Sprache sehr schwer für mich.","en":"At first the language was very hard for me.","ru":"Сначала язык давался мне очень тяжело.","vi":"Lúc đầu ngôn ngữ này rất khó đối với tôi.","fa":"در ابتدا زبان برای من بسیار سخت بود."},{"de":"Anfangs wollte er nicht mitkommen.","en":"Initially he did not want to come along.","ru":"Поначалу он не хотел идти с нами.","vi":"Lúc đầu anh ấy không muốn đến.","fa":"اولش نمی خواست بیاید."},{"de":"Sie war anfangs etwas schüchtern.","en":"She was a little shy at first.","ru":"Сначала она немного стеснялась.","vi":"Lúc đầu cô ấy hơi ngại ngùng.","fa":"او ابتدا کمی خجالتی بود."}]},{"word":"die Angabe","en":"detail, information, statement","ru":"сведение, данные, указание","vi":"thông tin","fa":"اطلاعات","examples":[{"de":"Bitte machen Sie genaue Angaben zu Ihrer Adresse.","en":"Please provide exact details about your address.","ru":"Пожалуйста, укажите точные данные о вашем адресе.","vi":"Vui lòng cung cấp thông tin chính xác về địa chỉ của bạn.","fa":"لطفا اطلاعات دقیق در مورد آدرس خود ارائه دهید."},{"de":"Ohne diese Angabe können wir Ihren Antrag nicht bearbeiten.","en":"Without this information we cannot process your application.","ru":"Без этого сведения мы не сможем обработать вашу заявку.","vi":"Nếu không có thông tin này, chúng tôi không thể xử lý đơn đăng ký của bạn.","fa":"بدون این اطلاعات ما نمی توانیم درخواست شما را پردازش کنیم."},{"de":"Die Angaben im Formular waren leider falsch.","en":"The details in the form were unfortunately wrong.","ru":"Данные в бланке, к сожалению, оказались неверными.","vi":"Rất tiếc, thông tin trong biểu mẫu không chính xác.","fa":"متأسفانه اطلاعات موجود در فرم نادرست بود."}]},{"word":"angeben","en":"to state, indicate; to show off","ru":"указывать; хвастаться","vi":"chỉ định","fa":"مشخص کنید","examples":[{"de":"Bitte geben Sie Ihren Namen und Ihre Adresse an.","en":"Please state your name and your address.","ru":"Пожалуйста, укажите ваше имя и адрес.","vi":"Vui lòng bao gồm tên và địa chỉ của bạn.","fa":"لطفا نام و آدرس خود را ذکر کنید."},{"de":"Er gibt gern mit seinem neuen Auto an.","en":"He likes to show off with his new car.","ru":"Он любит хвастаться своей новой машиной.","vi":"Anh ấy thích khoe chiếc xe mới của mình.","fa":"او دوست دارد ماشین جدیدش را به نمایش بگذارد."}]},{"word":"angeblich","en":"alleged, supposedly","ru":"якобы, предположительно; мнимый","vi":"được cho là","fa":"ظاهرا","examples":[{"de":"Er ist angeblich krank, aber niemand glaubt das.","en":"He is supposedly ill, but nobody believes it.","ru":"Он якобы болен, но никто в это не верит.","vi":"Người ta cho rằng anh ta bị bệnh, nhưng không ai tin điều đó.","fa":"او ظاهراً بیمار است، اما هیچ کس این را باور نمی کند."},{"de":"Das angebliche Geschenk war gar nicht für mich.","en":"The alleged gift was not for me at all.","ru":"Мнимый подарок был вовсе не для меня.","vi":"Món quà được cho là không dành cho tôi chút nào.","fa":"هدیه فرضی اصلا برای من نبود."},{"de":"Angeblich kommt morgen besseres Wetter.","en":"Supposedly the weather will be better tomorrow.","ru":"Якобы завтра будет погода получше.","vi":"Rõ ràng thời tiết tốt hơn sẽ đến vào ngày mai.","fa":"ظاهرا فردا هوا بهتر می شود."}]},{"word":"das Angebot","en":"offer","ru":"предложение","vi":"lời đề nghị","fa":"پیشنهاد","examples":[{"de":"Wir nehmen das Angebot gerne an.","en":"We're happy to accept the offer.","ru":"Мы с удовольствием принимаем предложение.","vi":"Chúng tôi vui vẻ chấp nhận lời đề nghị.","fa":"ما با کمال میل این پیشنهاد را می پذیریم."},{"de":"Im Supermarkt gibt es diese Woche ein gutes Angebot.","en":"There's a good offer at the supermarket this week.","ru":"На этой неделе в супермаркете есть выгодное предложение.","vi":"Có một món hời ở siêu thị tuần này.","fa":"این هفته یک معامله خوب در سوپرمارکت وجود دارد."},{"de":"Vielen Dank für Ihr freundliches Angebot.","en":"Thank you very much for your kind offer.","ru":"Большое спасибо за Ваше любезное предложение.","vi":"Cảm ơn lời đề nghị tử tế của bạn.","fa":"ممنون از پیشنهاد خوبتون"}]},{"word":"der Angehörige","en":"relative, family member","ru":"родственник","vi":"người thân","fa":"خویشاوند","examples":[{"de":"Nur nahe Angehörige durften den Patienten besuchen.","en":"Only close relatives were allowed to visit the patient.","ru":"Только близкие родственники могли навещать пациента.","vi":"Chỉ người thân mới được phép vào thăm bệnh nhân.","fa":"فقط بستگان نزدیک اجازه ملاقات با بیمار را داشتند."},{"de":"Sie kümmert sich um ihre kranken Angehörigen.","en":"She takes care of her sick relatives.","ru":"Она заботится о своих больных родственниках.","vi":"Cô chăm sóc người thân bị bệnh của mình.","fa":"او از بستگان بیمار خود مراقبت می کند."}]},{"word":"angeklagt","en":"accused; (as noun) the accused / defendant","ru":"обвиняемый; (сущ.) обвиняемый, подсудимый","vi":"bị buộc tội","fa":"متهم","examples":[{"de":"Dieser Anwalt arbeitet täglich mit Angeklagten.","en":"This lawyer works daily with defendants.","ru":"Этот адвокат ежедневно работает с подсудимыми.","vi":"Luật sư này làm việc với các bị cáo mỗi ngày.","fa":"این وکیل هر روز با متهمان کار می کند."},{"de":"Der Angeklagte schwieg während der ganzen Verhandlung.","en":"The defendant remained silent throughout the whole trial.","ru":"Обвиняемый молчал на протяжении всего процесса.","vi":"Bị cáo giữ im lặng suốt phiên tòa.","fa":"متهم در طول جلسه سکوت کرد."},{"de":"Die Angeklagte beteuerte vor Gericht ihre Unschuld.","en":"The accused woman protested her innocence in court.","ru":"Обвиняемая уверяла в суде в своей невиновности.","vi":"Bị cáo khẳng định mình vô tội trước tòa.","fa":"متهم در دادگاه به بی گناهی خود اعتراض کرد."}]},{"word":"angenehm","en":"pleasant","ru":"приятный","vi":"dễ chịu","fa":"دلپذیر","examples":[{"de":"Wir hatten einen sehr angenehmen Abend zusammen.","en":"We had a very pleasant evening together.","ru":"У нас был очень приятный вечер вместе.","vi":"Chúng tôi đã có một buổi tối rất vui vẻ bên nhau.","fa":"عصر بسیار خوبی را با هم سپری کردیم."},{"de":"Draußen herrscht heute eine angenehme Temperatur.","en":"There is a pleasant temperature outside today.","ru":"Сегодня на улице приятная температура.","vi":"Nhiệt độ bên ngoài hôm nay dễ chịu.","fa":"امروز هوای بیرون هوای مطبوعی است."}]},{"word":"angestellt","en":"employed; (as noun) employee","ru":"нанятый, работающий по найму; (сущ.) служащий","vi":"có việc làm","fa":"استخدام شده است","examples":[{"de":"In diesem Unternehmen arbeiten fünf Angestellte.","en":"Five employees work in this company.","ru":"В этой компании работают пять служащих.","vi":"Có năm nhân viên làm việc trong công ty này.","fa":"در این شرکت پنج کارمند مشغول به کار هستند."},{"de":"Sie ist seit drei Jahren bei einer Bank angestellt.","en":"She has been employed at a bank for three years.","ru":"Она работает в банке уже три года.","vi":"Cô ấy đã làm việc tại một ngân hàng được ba năm.","fa":"او سه سال است که در یک بانک استخدام شده است."},{"de":"Die Angestellten dürfen heute früher nach Hause gehen.","en":"The employees may go home earlier today.","ru":"Сегодня служащим можно уйти домой пораньше.","vi":"Hôm nay nhân viên được phép về nhà sớm hơn.","fa":"کارمندان امروز اجازه دارند زودتر به خانه بروند."}]},{"word":"der Angestellte","en":"employee (male)","ru":"служащий, сотрудник (мужчина)","vi":"nhân viên","fa":"کارمند","examples":[{"de":"Der Angestellte hat heute frei.","en":"The employee has the day off today.","ru":"У сотрудника сегодня выходной.","vi":"Hôm nay nhân viên được nghỉ.","fa":"کارمند امروز تعطیل است."},{"de":"Der Angestellte am Schalter war sehr freundlich.","en":"The employee at the counter was very friendly.","ru":"Сотрудник за стойкой был очень приветлив.","vi":"Nhân viên bán hàng ở quầy rất thân thiện.","fa":"کارمند پیشخوان بسیار صمیمی بود."},{"de":"Jeder Angestellte bekommt am Jahresende eine Prämie.","en":"Every employee gets a bonus at the end of the year.","ru":"Каждый сотрудник получает в конце года премию.","vi":"Mỗi nhân viên đều nhận được tiền thưởng vào cuối năm.","fa":"هر کارمند در پایان سال پاداش دریافت می کند."}]},{"word":"die Angst","en":"fear","ru":"страх","vi":"nỗi sợ hãi","fa":"ترس","examples":[{"de":"Sie hat große Angst vor Spinnen.","en":"She is very afraid of spiders.","ru":"Она очень боится пауков.","vi":"Cô ấy rất sợ nhện.","fa":"او خیلی از عنکبوت می ترسد."},{"de":"Ich hatte Angst, den Zug zu verpassen.","en":"I was afraid of missing the train.","ru":"Я боялся опоздать на поезд.","vi":"Tôi sợ lỡ chuyến tàu.","fa":"می ترسیدم قطار را از دست بدهم."}]},{"word":"ängstlich","en":"anxious, fearful, timid","ru":"боязливый, робкий, пугливый","vi":"lo lắng","fa":"مضطرب","examples":[{"de":"Das Kind ist sehr ängstlich, wenn es dunkel wird.","en":"The child is very anxious when it gets dark.","ru":"Ребёнок очень боится, когда темнеет.","vi":"Đứa trẻ rất lo lắng khi trời tối.","fa":"کودک هنگام تاریک شدن هوا بسیار مضطرب است."},{"de":"Sie warf einen ängstlichen Blick zur Tür.","en":"She cast an anxious glance towards the door.","ru":"Она бросила боязливый взгляд на дверь.","vi":"Cô đưa ánh mắt sợ hãi về phía cửa.","fa":"نگاهی ترسناک به در انداخت."},{"de":"Mein Hund ist ängstlich bei lauten Geräuschen.","en":"My dog is fearful of loud noises.","ru":"Моя собака пугается громких звуков.","vi":"Con chó của tôi sợ tiếng động lớn.","fa":"سگ من از صداهای بلند می ترسد."}]},{"word":"anhaben","en":"to be wearing","ru":"быть одетым в","vi":"có trên","fa":"دارند","examples":[{"de":"Sie hat heute ein rotes Kleid an.","en":"She is wearing a red dress today.","ru":"Сегодня на ней красное платье.","vi":"Hôm nay cô ấy mặc một chiếc váy màu đỏ.","fa":"اون امروز یه لباس قرمز پوشیده"},{"de":"Was hattest du gestern auf der Party an?","en":"What were you wearing at the party yesterday?","ru":"Что на тебе было надето вчера на вечеринке?","vi":"Bạn đã mặc gì đến bữa tiệc ngày hôm qua?","fa":"دیروز تو مهمونی چی پوشیدی؟"}]},{"word":"anklicken","en":"to click on","ru":"нажимать (мышью), кликать","vi":"bấm vào","fa":"کلیک کنید","examples":[{"de":"Klicken Sie auf das grüne Symbol, um fortzufahren.","en":"Click on the green icon to continue.","ru":"Нажмите на зелёный значок, чтобы продолжить.","vi":"Bấm vào biểu tượng màu xanh lá cây để tiếp tục.","fa":"برای ادامه روی آیکون سبز رنگ کلیک کنید."},{"de":"Ich habe versehentlich den falschen Link angeklickt.","en":"I accidentally clicked on the wrong link.","ru":"Я случайно кликнул не по той ссылке.","vi":"Tôi vô tình bấm vào liên kết sai.","fa":"من تصادفاً روی لینک اشتباه کلیک کردم."}]},{"word":"ankommen","en":"to arrive","ru":"прибывать, приезжать","vi":"đến","fa":"رسیدن","examples":[{"de":"Der Zug kommt um 14 Uhr in Berlin an.","en":"The train arrives in Berlin at 2 p.m.","ru":"Поезд прибывает в Берлин в 14:00.","vi":"Tàu đến Berlin lúc 2 giờ chiều.","fa":"قطار ساعت 2 بعد از ظهر به برلین می رسد."},{"de":"Wann kommst du morgen bei uns an?","en":"When will you arrive at our place tomorrow?","ru":"Когда ты завтра к нам приедешь?","vi":"Ngày mai khi nào bạn đến?","fa":"فردا کی میرسی؟"}]},{"word":"ankündigen","en":"to announce","ru":"объявлять, анонсировать","vi":"thông báo","fa":"اعلام کند","examples":[{"de":"Die Regierung hat neue Maßnahmen angekündigt.","en":"The government has announced new measures.","ru":"Правительство объявило о новых мерах.","vi":"Die Regierung hat neue Maßnahmen angekündigt.","fa":"دولت تدابیر جدیدی را اعلام کرده است."},{"de":"Der Sturm wurde schon gestern im Radio angekündigt.","en":"The storm was already announced on the radio yesterday.","ru":"О шторме уже вчера объявили по радио.","vi":"Cơn bão đã được thông báo trên đài phát thanh ngày hôm qua.","fa":"طوفان دیروز از رادیو اعلام شد."}]},{"word":"die Ankunft","en":"arrival","ru":"прибытие","vi":"sự xuất hiện","fa":"ورود","examples":[{"de":"Die Ankunft des Fluges verzögert sich um eine Stunde.","en":"The flight's arrival is delayed by an hour.","ru":"Прибытие рейса задерживается на час.","vi":"Chuyến bay đến bị trì hoãn một giờ.","fa":"رسیدن پرواز یک ساعت تاخیر دارد."},{"de":"Bei unserer Ankunft schien die Sonne.","en":"The sun was shining upon our arrival.","ru":"К нашему прибытию светило солнце.","vi":"Mặt trời đang chiếu sáng khi chúng tôi đến.","fa":"وقتی رسیدیم خورشید داشت می درخشید."}]},{"word":"die Anlage","en":"facility, plant; enclosure","ru":"установка, комплекс; приложение (к письму)","vi":"cơ sở","fa":"تسهیلات","examples":[{"de":"In der Nähe der Stadt gibt es eine große Sportanlage.","en":"Near the city there is a large sports facility.","ru":"Недалеко от города есть большой спортивный комплекс.","vi":"Có một khu liên hợp thể thao lớn gần thành phố.","fa":"یک مجموعه ورزشی بزرگ در نزدیکی شهر وجود دارد."},{"de":"Die Rechnung finden Sie in der Anlage zu dieser E-Mail.","en":"You will find the invoice in the attachment to this email.","ru":"Счёт вы найдёте в приложении к этому письму.","vi":"Bạn có thể tìm thấy hóa đơn được đính kèm với email này.","fa":"شما می توانید فاکتور پیوست شده به این ایمیل را پیدا کنید."}]},{"word":"die Anleitung","en":"instructions, manual","ru":"инструкция","vi":"hướng dẫn","fa":"دستورالعمل ها","examples":[{"de":"Lesen Sie zuerst die Anleitung, bevor Sie das Gerät benutzen.","en":"Read the instructions first before using the device.","ru":"Сначала прочитайте инструкцию, прежде чем пользоваться устройством.","vi":"Đọc hướng dẫn trước khi sử dụng thiết bị.","fa":"قبل از استفاده از دستگاه ابتدا دستورالعمل ها را بخوانید."},{"de":"Die Anleitung zum Zusammenbau des Regals war leicht verständlich.","en":"The instructions for assembling the shelf were easy to understand.","ru":"Инструкция по сборке полки была легко понятна.","vi":"Die Anleitung zum Zusammenbau des Regals war leicht verständlich.","fa":"دستورالعمل های مونتاژ قفسه به راحتی قابل درک بود."}]},{"word":"anmachen","en":"to switch on, turn on; to dress (a salad)","ru":"включать; заправлять (салат)","vi":"bật lên","fa":"روشن کن","examples":[{"de":"Mach bitte das Licht an, es ist dunkel.","en":"Please switch the light on, it's dark.","ru":"Включи, пожалуйста, свет, темно.","vi":"Làm ơn bật đèn lên, trời tối quá.","fa":"لطفا چراغ را روشن کنید، تاریک است."},{"de":"Ich mache den Fernseher an.","en":"I'm turning the television on.","ru":"Я включаю телевизор.","vi":"Tôi bật tivi.","fa":"تلویزیون را روشن می کنم."},{"de":"Kannst du den Ofen anmachen?","en":"Can you turn the oven on?","ru":"Можешь включить духовку?","vi":"Bạn có thể bật lò nướng được không?","fa":"میشه فر رو روشن کنی؟"}]},{"word":"anmelden","en":"to register","ru":"регистрировать(ся), записывать(ся)","vi":"đăng nhập","fa":"وارد شوید","examples":[{"de":"Ich muss mich noch für den Deutschkurs anmelden.","en":"I still have to register for the German course.","ru":"Мне ещё нужно записаться на курс немецкого языка.","vi":"Tôi vẫn phải đăng ký khóa học tiếng Đức.","fa":"هنوز باید برای دوره آلمانی ثبت نام کنم."},{"de":"Neue Bewohner müssen sich innerhalb von zwei Wochen anmelden.","en":"New residents have to register within two weeks.","ru":"Новые жители должны зарегистрироваться в течение двух недель.","vi":"Cư dân mới phải đăng ký trong vòng hai tuần.","fa":"ساکنین جدید باید ظرف دو هفته ثبت نام کنند."}]},{"word":"die Anmeldung","en":"registration; sign-up","ru":"регистрация; запись","vi":"việc đăng ký","fa":"ثبت نام","examples":[{"de":"Die Anmeldung für den Kurs ist ab Montag möglich.","en":"Registration for the course is possible from Monday.","ru":"Запись на курс возможна с понедельника.","vi":"Có thể đăng ký khóa học từ thứ Hai.","fa":"ثبت نام دوره از روز دوشنبه امکان پذیر است."},{"de":"Nach dem Umzug muss man zur Anmeldung aufs Amt.","en":"After moving you have to go to the office to register.","ru":"После переезда нужно пойти в учреждение на регистрацию.","vi":"Sau khi chuyển đi bạn phải đến văn phòng để đăng ký.","fa":"پس از اسباب کشی برای ثبت نام باید به دفتر مراجعه کنید."}]},{"word":"anmutig","en":"graceful","ru":"грациозный, изящный","vi":"duyên dáng","fa":"برازنده","examples":[{"de":"Die Tänzerin bewegte sich anmutig zur Musik.","en":"The dancer moved gracefully to the music.","ru":"Танцовщица грациозно двигалась под музыку.","vi":"Cô vũ công uyển chuyển di chuyển theo điệu nhạc.","fa":"رقصنده با زیبایی به سمت موسیقی حرکت کرد."},{"de":"Mit anmutigen Schritten überquerte sie die Bühne.","en":"With graceful steps she crossed the stage.","ru":"Изящными шагами она пересекла сцену.","vi":"Cô bước qua sân khấu với những bước đi duyên dáng.","fa":"او با قدم هایی زیبا از صحنه گذشت."},{"de":"Sein Tanz war kraftvoll und zugleich anmutig.","en":"His dance was powerful and graceful at the same time.","ru":"Его танец был одновременно мощным и грациозным.","vi":"Điệu nhảy của anh ấy đồng thời mạnh mẽ và duyên dáng.","fa":"رقص او در عین حال قدرتمند و زیبا بود."}]},{"word":"annehmen","en":"to accept; to assume","ru":"принимать; предполагать","vi":"chấp nhận","fa":"قبول کنید","examples":[{"de":"Sie hat das Geschenk dankend angenommen.","en":"She gratefully accepted the gift.","ru":"Она с благодарностью приняла подарок.","vi":"She gratefully accepted the gift.","fa":"او با قدردانی هدیه را پذیرفت."},{"de":"Ich nehme an, dass er morgen wieder da ist.","en":"I assume that he will be back tomorrow.","ru":"Я предполагаю, что завтра он снова будет на месте.","vi":"Tôi cho rằng anh ấy sẽ trở lại vào ngày mai.","fa":"فکر کنم فردا برمیگرده"}]},{"word":"die Annonce","en":"advertisement, classified ad","ru":"объявление","vi":"quảng cáo","fa":"تبلیغ","examples":[{"de":"Er hat die Wohnung durch eine Annonce in der Zeitung gefunden.","en":"He found the apartment through an ad in the newspaper.","ru":"Он нашёл квартиру через объявление в газете.","vi":"Anh tìm thấy căn hộ thông qua một quảng cáo trên báo.","fa":"او آپارتمان را از طریق یک آگهی در روزنامه پیدا کرد."},{"de":"Sie hat eine Annonce aufgegeben, um ihr altes Auto zu verkaufen.","en":"She placed an ad to sell her old car.","ru":"Она подала объявление, чтобы продать свою старую машину.","vi":"Cô ấy đăng một quảng cáo để bán chiếc xe cũ của mình.","fa":"او یک آگهی برای فروش ماشین قدیمی خود گذاشت."}]},{"word":"anonym","en":"anonymous","ru":"анонимный","vi":"vô danh","fa":"ناشناس","examples":[{"de":"Die Umfrage ist völlig anonym.","en":"The survey is completely anonymous.","ru":"Опрос полностью анонимный.","vi":"Cuộc khảo sát hoàn toàn ẩn danh.","fa":"نظرسنجی کاملاً ناشناس است."},{"de":"Wir speichern die Daten anonym.","en":"We store the data anonymously.","ru":"Мы храним данные анонимно.","vi":"Chúng tôi lưu trữ dữ liệu ẩn danh.","fa":"ما داده ها را به صورت ناشناس ذخیره می کنیم."},{"de":"Anonyme Daten verraten nicht, wer du bist.","en":"Anonymous data does not reveal who you are.","ru":"Анонимные данные не раскрывают, кто ты.","vi":"Dữ liệu ẩn danh không tiết lộ bạn là ai.","fa":"داده های ناشناس نشان نمی دهد که شما کی هستید."}]},{"word":"die Anpassung","en":"adaptation, conformity","ru":"приспособление, адаптация; конформизм","vi":"sự thích ứng","fa":"سازگاری","examples":[{"de":"Die Anpassung an eine neue Kultur braucht Zeit.","en":"Adapting to a new culture takes time.","ru":"Адаптация к новой культуре требует времени.","vi":"Việc thích nghi với một nền văn hóa mới cần có thời gian.","fa":"سازگاری با فرهنگ جدید زمان می برد."},{"de":"Zu viel Anpassung kann die eigene Persönlichkeit verbergen.","en":"Too much conformity can hide one's own personality.","ru":"Слишком большой конформизм может скрыть собственную личность.","vi":"Tùy chỉnh quá nhiều có thể che giấu tính cách của một người.","fa":"سفارشی سازی بیش از حد می تواند شخصیت فرد را پنهان کند."},{"de":"Anpassung an die Gruppe fällt manchen Menschen leicht.","en":"Adapting to the group comes easily to some people.","ru":"Приспособление к группе некоторым людям даётся легко.","vi":"Việc thích nghi với nhóm là điều dễ dàng đối với một số người.","fa":"سازگاری با گروه برای برخی افراد آسان است."}]},{"word":"die Anrede","en":"form of address, salutation","ru":"обращение (в письме)","vi":"lời chào","fa":"سلام","examples":[{"de":"In einem formellen Brief benutzt man die Anrede „Sehr geehrte Damen und Herren“.","en":"In a formal letter one uses the salutation 'Dear Sir or Madam'.","ru":"В официальном письме используется обращение «Уважаемые дамы и господа».","vi":"Trong một bức thư trang trọng, lời chào “Dear Sir or Madam” được sử dụng.","fa":"در نامه رسمی از سلام آقا یا خانم عزیز استفاده شده است."},{"de":"Welche Anrede ist bei einer E-Mail an den Professor passend?","en":"Which form of address is appropriate for an email to the professor?","ru":"Какое обращение уместно в письме профессору?","vi":"Lời chào nào là phù hợp khi gửi email cho giáo sư?","fa":"هنگام ارسال ایمیل به استاد چه سلامی مناسب است؟"}]},{"word":"anreisen","en":"to travel to, arrive","ru":"приезжать, прибывать","vi":"đến","fa":"رسیدن","examples":[{"de":"Die Gäste reisen morgen früh an.","en":"The guests are arriving tomorrow morning.","ru":"Гости приезжают завтра утром.","vi":"Khách đến vào sáng mai.","fa":"مهمانان فردا صبح می آیند."},{"de":"Wir sind mit dem Zug angereist.","en":"We travelled here by train.","ru":"Мы приехали сюда на поезде.","vi":"Chúng tôi đến bằng tàu hỏa.","fa":"با قطار رسیدیم."},{"de":"Viele Touristen reisen aus dem Ausland an.","en":"Many tourists travel here from abroad.","ru":"Многие туристы приезжают сюда из-за границы.","vi":"Nhiều khách du lịch đến từ nước ngoài.","fa":"گردشگران زیادی از خارج از کشور می آیند."}]},{"word":"der Anrufbeantworter","en":"answering machine","ru":"автоответчик","vi":"máy trả lời","fa":"منشی تلفنی","examples":[{"de":"Er war nicht zu Hause, also sprach ich auf den Anrufbeantworter.","en":"He wasn't home, so I left a message on the answering machine.","ru":"Его не было дома, поэтому я оставил сообщение на автоответчике.","vi":"Anh ấy không có nhà nên tôi để lại máy trả lời tự động.","fa":"او خانه نبود، من از منشی تلفنی خارج شدم."},{"de":"Bitte hinterlassen Sie nach dem Ton eine Nachricht auf dem Anrufbeantworter.","en":"Please leave a message on the answering machine after the beep.","ru":"Пожалуйста, оставьте сообщение на автоответчике после сигнала.","vi":"Vui lòng để lại tin nhắn trên máy trả lời sau tiếng chuông.","fa":"لطفا بعد از تون در منشی تلفنی پیام بگذارید."}]},{"word":"anrufen","en":"to call, to phone","ru":"звонить","vi":"gọi","fa":"تماس بگیرید","examples":[{"de":"Ruf mich bitte an, wenn du angekommen bist.","en":"Please call me when you have arrived.","ru":"Позвони мне, пожалуйста, когда приедешь.","vi":"Hãy gọi cho tôi khi bạn đến.","fa":"لطفا وقتی رسیدی با من تماس بگیر"},{"de":"Ich habe dich dreimal angerufen, aber niemand hat abgehoben.","en":"I called you three times, but nobody picked up.","ru":"Я звонил тебе три раза, но никто не ответил.","vi":"Tôi gọi cho bạn ba lần nhưng không ai bắt máy.","fa":"من سه بار با شما تماس گرفتم اما کسی نگرفت."}]},{"word":"die Ansage","en":"announcement","ru":"объявление (устное)","vi":"thông báo","fa":"اعلامیه","examples":[{"de":"Wegen einer Durchsage konnten wir die Ansage am Bahnhof kaum verstehen.","en":"Because of the announcement, we could hardly understand the message at the station.","ru":"Из-за объявления мы едва могли расслышать сообщение на вокзале.","vi":"Vì một thông báo nên chúng tôi khó có thể hiểu được thông báo ở ga xe lửa.","fa":"به دلیل یک اعلامیه، ما به سختی می‌توانستیم اطلاعیه ایستگاه قطار را بفهمیم."},{"de":"Die Ansage im Flugzeug informierte uns über die Landung.","en":"The announcement on the plane informed us about the landing.","ru":"Объявление в самолёте сообщило нам о посадке.","vi":"Thông báo trên máy bay thông báo cho chúng tôi về việc hạ cánh.","fa":"اعلامیه هواپیما به ما خبر فرود می داد."}]},{"word":"anschaffen","en":"to acquire, to purchase","ru":"приобретать","vi":"có được","fa":"بدست آوردن","examples":[{"de":"Wir wollen uns bald einen neuen Kühlschrank anschaffen.","en":"We want to acquire a new refrigerator soon.","ru":"Мы скоро хотим приобрести новый холодильник.","vi":"We want to buy a new refrigerator soon.","fa":"ما می خواهیم به زودی یک یخچال جدید بخریم."},{"de":"Er hat sich ein teures Fahrrad angeschafft.","en":"He acquired an expensive bicycle.","ru":"Он приобрёл дорогой велосипед.","vi":"Anh ấy đã mua một chiếc xe đạp đắt tiền.","fa":"او یک دوچرخه گران قیمت خرید."}]},{"word":"anschließen","en":"to connect; to join","ru":"подключать; присоединяться","vi":"kết nối","fa":"اتصال","examples":[{"de":"Kannst du bitte den Drucker an den Computer anschließen?","en":"Can you please connect the printer to the computer?","ru":"Можешь, пожалуйста, подключить принтер к компьютеру?","vi":"Bạn có thể vui lòng kết nối máy in với máy tính được không?","fa":"آیا می توانید چاپگر را به کامپیوتر وصل کنید؟"},{"de":"Ich schließe mich deiner Meinung an.","en":"I agree with (join) your opinion.","ru":"Я присоединяюсь к твоему мнению.","vi":"Ich schließe mich deiner Meinung an.","fa":"من با نظر شما موافقم"}]},{"word":"der Anschluss","en":"connection","ru":"соединение, подключение","vi":"sự kết nối","fa":"اتصال","examples":[{"de":"In Frankfurt haben wir Anschluss an den Zug nach München.","en":"In Frankfurt we have a connection to the train to Munich.","ru":"Во Франкфурте у нас пересадка на поезд в Мюнхен.","vi":"Tại Frankfurt, chúng tôi kết nối tàu đến Munich.","fa":"در فرانکفورت به قطار مونیخ متصل می شویم."},{"de":"Wir brauchen einen schnelleren Internetanschluss.","en":"We need a faster internet connection.","ru":"Нам нужно более быстрое подключение к интернету.","vi":"Chúng tôi cần kết nối internet nhanh hơn.","fa":"ما به اینترنت سریعتر نیاز داریم."}]},{"word":"anschnallen","en":"to fasten (a seatbelt)","ru":"пристёгивать(ся)","vi":"thắt dây an toàn","fa":"بستن کمربند","examples":[{"de":"Bitte schnallen Sie sich an, bevor das Auto losfährt.","en":"Please fasten your seatbelt before the car starts driving.","ru":"Пожалуйста, пристегнитесь, прежде чем машина тронется.","vi":"Vui lòng thắt dây an toàn trước khi xe chạy đi.","fa":"لطفا قبل از پیاده شدن خودرو کمربند ایمنی خود را ببندید."},{"de":"Alle Passagiere müssen sich beim Start anschnallen.","en":"All passengers must fasten their seatbelts during takeoff.","ru":"Все пассажиры должны пристегнуться во время взлёта.","vi":"Tất cả hành khách phải thắt dây an toàn khi cất cánh.","fa":"همه مسافران هنگام بلند شدن باید کمربند ایمنی خود را ببندند."}]},{"word":"ansehen","en":"to look at, to watch","ru":"смотреть, рассматривать","vi":"lượt xem","fa":"مشاهده کنید","examples":[{"de":"Wollen wir uns heute Abend einen Film ansehen?","en":"Shall we watch a movie tonight?","ru":"Может, посмотрим сегодня вечером фильм?","vi":"Tối nay chúng ta cùng xem phim nhé?","fa":"امشب فیلم ببینیم؟"},{"de":"Er sah sich die Fotos lange an.","en":"He looked at the photos for a long time.","ru":"Он долго рассматривал фотографии.","vi":"Anh nhìn những bức ảnh rất lâu.","fa":"مدت زیادی به عکس ها نگاه کرد."}]},{"word":"die Anspannung","en":"tension","ru":"напряжение","vi":"sự căng thẳng","fa":"تنش","examples":[{"de":"Spüre die Anspannung in deinen Schultern und lass sie los.","en":"Feel the tension in your shoulders and let it go.","ru":"Почувствуй напряжение в плечах и отпусти его.","vi":"Hãy cảm nhận sự căng thẳng ở vai và để nó trôi qua.","fa":"تنش را در شانه های خود احساس کنید و آن را رها کنید."},{"de":"Beim Ausatmen verschwindet die Anspannung langsam.","en":"As you breathe out the tension slowly disappears.","ru":"На выдохе напряжение медленно уходит.","vi":"Khi bạn thở ra, sự căng thẳng dần dần biến mất.","fa":"با بازدم، تنش به آرامی از بین می رود."},{"de":"Stress führt oft zu Anspannung im Nacken.","en":"Stress often leads to tension in the neck.","ru":"Стресс часто приводит к напряжению в шее.","vi":"Căng thẳng thường dẫn đến căng thẳng ở cổ.","fa":"استرس اغلب منجر به تنش در گردن می شود."}]},{"word":"ansprechen","en":"to address, to speak to","ru":"обращаться (к кому-то), заговаривать","vi":"địa chỉ","fa":"آدرس","examples":[{"de":"Eine fremde Frau sprach mich auf der Straße an.","en":"A stranger (woman) spoke to me on the street.","ru":"Незнакомая женщина заговорила со мной на улице.","vi":"Eine fremde Frau sprach mich auf der Straße an.","fa":"زنی غریبه در خیابان با من صحبت کرد."},{"de":"Ich möchte dieses Thema kurz ansprechen.","en":"I would like to briefly address this topic.","ru":"Я хотел бы кратко затронуть эту тему.","vi":"Tôi muốn giải quyết ngắn gọn chủ đề này.","fa":"من می خواهم به طور خلاصه به این موضوع بپردازم."}]},{"word":"der Ansprechpartner","en":"contact person","ru":"контактное лицо, ответственный сотрудник","vi":"người liên lạc","fa":"شخص تماس","examples":[{"de":"Wer ist mein Ansprechpartner für diese Frage?","en":"Who is my contact person for this question?","ru":"Кто мой контакт по этому вопросу?","vi":"Người liên hệ của tôi cho câu hỏi này là ai?","fa":"مخاطب من برای این سوال کیست؟"},{"de":"Der Ansprechpartner im Büro hilft Ihnen gerne weiter.","en":"The contact person in the office will be glad to help you.","ru":"Ответственный сотрудник в офисе охотно вам поможет.","vi":"Người liên hệ tại văn phòng sẽ sẵn lòng giúp đỡ bạn.","fa":"مسئول تماس در دفتر خوشحال خواهد شد که به شما کمک کند."},{"de":"Bitte wenden Sie sich an Ihren zuständigen Ansprechpartner.","en":"Please contact the responsible contact person.","ru":"Пожалуйста, обратитесь к вашему ответственному сотруднику.","vi":"Vui lòng liên hệ với người liên hệ chịu trách nhiệm của bạn.","fa":"لطفا با مسئول تماس خود تماس بگیرید."}]},{"word":"der Anspruch","en":"claim, entitlement","ru":"право, притязание","vi":"yêu cầu bồi thường","fa":"ادعا","examples":[{"de":"Sie hat Anspruch auf drei Wochen Urlaub im Jahr.","en":"She is entitled to three weeks of vacation per year.","ru":"Она имеет право на три недели отпуска в год.","vi":"Cô được hưởng ba tuần nghỉ phép mỗi năm.","fa":"او حق دارد سه هفته مرخصی در سال داشته باشد."},{"de":"Er erhebt keinen Anspruch auf das Erbe seines Onkels.","en":"He does not claim any right to his uncle's inheritance.","ru":"Он не претендует на наследство своего дяди.","vi":"Anh ta tuyên bố không có yêu cầu gì về quyền thừa kế của chú mình.","fa":"او ادعایی در مورد ارث عمویش ندارد."}]},{"word":"anspruchsvoll","en":"demanding, challenging","ru":"требовательный, сложный, ответственный (о задаче)","vi":"đòi hỏi khắt khe","fa":"مطالبه گر","examples":[{"de":"Die neue Aufgabe ist sehr anspruchsvoll, aber interessant.","en":"The new task is very demanding, but interesting.","ru":"Новая задача очень сложная, но интересная.","vi":"Nhiệm vụ mới rất khắt khe nhưng thú vị.","fa":"کار جدید بسیار سخت اما جالب است."},{"de":"Er sucht eine anspruchsvolle Tätigkeit mit viel Verantwortung.","en":"He's looking for a challenging job with a lot of responsibility.","ru":"Он ищет ответственную работу с большой самостоятельностью.","vi":"Anh ấy đang tìm kiếm một công việc đầy thử thách với nhiều trách nhiệm.","fa":"او به دنبال شغلی چالش برانگیز با مسئولیت زیاد است."},{"de":"Unsere Kunden sind anspruchsvoll und erwarten beste Qualität.","en":"Our customers are demanding and expect the best quality.","ru":"Наши клиенты требовательны и ждут лучшего качества.","vi":"Khách hàng của chúng tôi luôn đòi hỏi và mong đợi chất lượng tốt nhất.","fa":"مشتریان ما خواستار هستند و انتظار بهترین کیفیت را دارند."}]},{"word":"anstellen","en":"to employ, hire; to turn on","ru":"нанимать; включать; вставать в очередь","vi":"thuê","fa":"استخدام کنید","examples":[{"de":"Die Firma hat letzten Monat drei neue Mitarbeiter angestellt.","en":"The company hired three new employees last month.","ru":"В прошлом месяце компания наняла трёх новых сотрудников.","vi":"Công ty đã thuê ba nhân viên mới vào tháng trước.","fa":"این شرکت ماه گذشته سه کارمند جدید استخدام کرد."},{"de":"Wir mussten uns lange an der Kasse anstellen.","en":"We had to queue up for a long time at the checkout.","ru":"Нам пришлось долго стоять в очереди у кассы.","vi":"We had to queue for a long time at the checkout.","fa":"ما مجبور شدیم برای مدت طولانی در صندوق خانه صف بکشیم."}]},{"word":"der Anstieg","en":"rise, increase","ru":"подъём, рост, повышение","vi":"sự gia tăng","fa":"افزایش","examples":[{"de":"Der Anstieg der Temperaturen bedroht viele Küstenstädte.","en":"The rise in temperatures threatens many coastal cities.","ru":"Рост температур угрожает многим прибрежным городам.","vi":"Nhiệt độ tăng đe dọa nhiều thành phố ven biển.","fa":"افزایش دما بسیاری از شهرهای ساحلی را تهدید می کند."},{"de":"Forscher warnen vor einem weiteren Anstieg der CO2-Werte.","en":"Researchers are warning of a further increase in CO2 levels.","ru":"Учёные предупреждают о дальнейшем росте уровня CO2.","vi":"Các nhà nghiên cứu cảnh báo về sự gia tăng hơn nữa nồng độ CO2.","fa":"محققان در مورد افزایش بیشتر سطح CO2 هشدار می دهند."},{"de":"Der Anstieg des Meeres ist eine Folge der Erwärmung.","en":"The rise of the sea is a consequence of the warming.","ru":"Подъём уровня моря — следствие потепления.","vi":"Nước biển dâng lên là kết quả của sự nóng lên.","fa":"بالا آمدن دریا نتیجه گرم شدن هواست."}]},{"word":"anstrengen","en":"to exert oneself, make an effort; to strain","ru":"напрягаться, стараться; утомлять, напрягать","vi":"nỗ lực","fa":"تلاش کن","examples":[{"de":"Du musst dich mehr anstrengen, um die Prüfung zu bestehen.","en":"You have to make more of an effort to pass the exam.","ru":"Тебе нужно больше стараться, чтобы сдать экзамен.","vi":"Bạn phải cố gắng hơn nữa để vượt qua kỳ thi.","fa":"برای قبولی در امتحان باید بیشتر تلاش کنید."},{"de":"Die lange Wanderung hat mich sehr angestrengt.","en":"The long hike exhausted me a lot.","ru":"Долгий поход меня сильно утомил.","vi":"Việc đi bộ đường dài khiến tôi rất mệt mỏi.","fa":"پیاده روی طولانی برای من بسیار خسته کننده بود."},{"de":"Streng dich an, dann schaffst du es.","en":"Make an effort and you'll manage it.","ru":"Постарайся — и у тебя получится.","vi":"Hãy nỗ lực và bạn sẽ làm được.","fa":"تلاش کن موفق میشی"}]},{"word":"anstrengend","en":"strenuous, tiring, exhausting","ru":"утомительный, изнурительный, напряжённый","vi":"mệt mỏi","fa":"خسته کننده","examples":[{"de":"Der Tag im Büro war sehr anstrengend.","en":"The day at the office was very tiring.","ru":"День в офисе был очень утомительным.","vi":"Một ngày ở văn phòng thật mệt mỏi.","fa":"آن روز در دفتر بسیار خسته کننده بود."},{"de":"Wandern in den Bergen ist anstrengend.","en":"Hiking in the mountains is strenuous.","ru":"Ходить в горы утомительно.","vi":"Đi bộ trên núi thật vất vả.","fa":"پیاده روی در کوه ها سخت است."},{"de":"Sie hat einen anstrengenden Job.","en":"She has a demanding job.","ru":"У неё напряжённая работа.","vi":"Cô ấy có một công việc căng thẳng.","fa":"او شغل پر استرسی دارد."}]},{"word":"die Anstrengung","en":"exertion, effort","ru":"усилие, напряжение","vi":"nỗ lực","fa":"تلاش","examples":[{"de":"Die Anstrengung hat sich gelohnt.","en":"The effort paid off.","ru":"Усилие себя оправдало.","vi":"Nỗ lực đó là xứng đáng.","fa":"تلاش ارزشش را داشت."},{"de":"Nach der Anstrengung ruhte er sich aus.","en":"After the exertion he rested.","ru":"После напряжения он отдохнул.","vi":"Sau khi gắng sức, anh ấy đã nghỉ ngơi.","fa":"بعد از تمرین استراحت کرد."},{"de":"Es kostete große Anstrengung.","en":"It took great effort.","ru":"Это стоило больших усилий.","vi":"Phải mất rất nhiều nỗ lực.","fa":"تلاش زیادی لازم بود."}]},{"word":"der Anteil","en":"proportion, share","ru":"доля","vi":"sự chia sẻ","fa":"سهم","examples":[{"de":"Der Anteil der Frauen in der Gruppe ist hoch.","en":"The proportion of women in the group is high.","ru":"Доля женщин в группе высока.","vi":"Tỷ lệ nữ trong nhóm cao.","fa":"نسبت زنان در این گروه زیاد است."},{"de":"Wir berechnen den Anteil in Prozent.","en":"We calculate the proportion as a percentage.","ru":"Мы вычисляем долю в процентах.","vi":"Chúng tôi tính toán tỷ lệ theo phần trăm.","fa":"سهم را بر حسب درصد محاسبه می کنیم."},{"de":"Der Anteil der fehlerhaften Daten ist klein.","en":"The proportion of faulty data is small.","ru":"Доля ошибочных данных мала.","vi":"Tỷ lệ dữ liệu không chính xác là nhỏ.","fa":"نسبت داده های نادرست کم است."}]},{"word":"die Antike","en":"antiquity, classical antiquity","ru":"античность","vi":"thế giới cổ đại","fa":"the ancient world","examples":[{"de":"In der Antike waren Griechenland und Rom besonders mächtig.","en":"In antiquity Greece and Rome were especially powerful.","ru":"В античности Греция и Рим были особенно могущественны.","vi":"Hy Lạp và La Mã đặc biệt hùng mạnh vào thời cổ đại.","fa":"یونان و روم به ویژه در دوران باستان قدرتمند بودند."},{"de":"Viele Ideen der Antike prägen unsere Kultur bis heute.","en":"Many ideas from antiquity shape our culture to this day.","ru":"Многие идеи античности определяют нашу культуру и по сей день.","vi":"Nhiều ý tưởng từ thời cổ đại vẫn định hình nền văn hóa của chúng ta ngày nay.","fa":"بسیاری از ایده ها از دوران باستان هنوز فرهنگ ما را شکل می دهند."},{"de":"Die Philosophie der Antike fasziniert noch immer viele Menschen.","en":"The philosophy of antiquity still fascinates many people.","ru":"Философия античности всё ещё увлекает многих людей.","vi":"Những triết lý cổ xưa vẫn mê hoặc nhiều người.","fa":"فلسفه دوران باستان هنوز هم افراد زیادی را مجذوب خود می کند."}]},{"word":"der Antrag","en":"application, request (formal)","ru":"заявление, ходатайство","vi":"ứng dụng","fa":"برنامه","examples":[{"de":"Sie hat einen Antrag auf Kindergeld gestellt.","en":"She submitted an application for child benefit.","ru":"Она подала заявление на получение пособия на ребёнка.","vi":"Cô ấy đã nộp đơn xin trợ cấp nuôi con.","fa":"او درخواست کمک هزینه فرزند کرده است."},{"de":"Der Antrag auf ein Visum kann online gestellt werden.","en":"The application for a visa can be submitted online.","ru":"Заявление на визу можно подать онлайн.","vi":"Đơn xin thị thực có thể được nộp trực tuyến.","fa":"درخواست ویزا را می توان به صورت آنلاین ارسال کرد."}]},{"word":"antworten","en":"to answer","ru":"отвечать","vi":"câu trả lời","fa":"پاسخ دهید","examples":[{"de":"Bitte antworten Sie mir bis Freitag auf meine E-Mail.","en":"Please reply to my email by Friday.","ru":"Пожалуйста, ответьте мне на письмо до пятницы.","vi":"Vui lòng trả lời email của tôi trước thứ Sáu.","fa":"لطفا تا جمعه به ایمیل من پاسخ دهید."},{"de":"Er antwortete nicht auf meine Frage.","en":"He did not answer my question.","ru":"Он не ответил на мой вопрос.","vi":"Anh ấy không trả lời câu hỏi của tôi.","fa":"به سوال من جواب نداد"}]},{"word":"der Anwalt","en":"lawyer","ru":"адвокат","vi":"luật sư","fa":"وکیل","examples":[{"de":"Sie hat einen Anwalt eingeschaltet, um ihre Rechte durchzusetzen.","en":"She engaged a lawyer to enforce her rights.","ru":"Она наняла адвоката, чтобы отстоять свои права.","vi":"Cô đã thuê luật sư để thực thi quyền lợi của mình.","fa":"او برای احقاق حقوق خود وکیل گرفت."},{"de":"Mein Bruder arbeitet als Anwalt in einer großen Kanzlei.","en":"My brother works as a lawyer at a large law firm.","ru":"Мой брат работает адвокатом в крупной юридической фирме.","vi":"Anh trai tôi làm luật sư ở một công ty luật lớn.","fa":"برادرم در یک موسسه حقوقی بزرگ به عنوان وکیل کار می کند."}]},{"word":"die Anwältin","en":"lawyer (female)","ru":"адвокат, юрист (ж.)","vi":"luật sư","fa":"وکیل","examples":[{"de":"Meine Anwältin hat mir bei dem Vertrag geholfen.","en":"My lawyer helped me with the contract.","ru":"Моя адвокат помогла мне с договором.","vi":"Luật sư của tôi đã giúp tôi về hợp đồng.","fa":"وکیلم در قرارداد به من کمک کرد."},{"de":"Die Anwältin verteidigt ihren Mandanten vor Gericht.","en":"The lawyer defends her client in court.","ru":"Адвокат защищает своего клиента в суде.","vi":"Luật sư bào chữa cho thân chủ của mình trước tòa.","fa":"وکیل در دادگاه از موکل خود دفاع می کند."},{"de":"Sie ist eine bekannte Anwältin für Arbeitsrecht.","en":"She is a well-known lawyer for employment law.","ru":"Она известная адвокат по трудовому праву.","vi":"Cô ấy là một luật sư luật lao động nổi tiếng.","fa":"او یک وکیل مشهور حقوق کار است."}]},{"word":"anwenden","en":"to apply, to use","ru":"применять","vi":"áp dụng","fa":"اعمال شود","examples":[{"de":"Man sollte die neuen Regeln in der Praxis anwenden.","en":"One should apply the new rules in practice.","ru":"Новые правила следует применять на практике.","vi":"Các quy định mới nên được áp dụng vào thực tế.","fa":"قوانین جدید باید در عمل اعمال شود."},{"de":"Diese Methode wird häufig in der Medizin angewendet.","en":"This method is often used in medicine.","ru":"Этот метод часто применяется в медицине.","vi":"Phương pháp này thường được sử dụng trong y học.","fa":"این روش اغلب در پزشکی استفاده می شود."}]},{"word":"die Anwendung","en":"application (a piece of software)","ru":"приложение (программа); применение","vi":"ứng dụng","fa":"برنامه","examples":[{"de":"Diese Anwendung verbraucht zu viel Arbeitsspeicher.","en":"This application uses up too much memory.","ru":"Это приложение потребляет слишком много оперативной памяти.","vi":"Ứng dụng này đang sử dụng quá nhiều bộ nhớ.","fa":"این برنامه از حافظه بیش از حد استفاده می کند."},{"de":"Lade die Anwendung aus dem App-Store herunter.","en":"Download the application from the app store.","ru":"Скачай приложение из магазина приложений.","vi":"Tải xuống ứng dụng từ App Store.","fa":"برنامه را از اپ استور دانلود کنید."},{"de":"Die neue Anwendung erleichtert uns die tägliche Arbeit sehr.","en":"The new application makes our daily work much easier.","ru":"Новое приложение сильно облегчает нам ежедневную работу.","vi":"Ứng dụng mới giúp công việc hàng ngày của chúng tôi dễ dàng hơn nhiều.","fa":"برنامه جدید کار روزانه ما را بسیار آسان می کند."}]},{"word":"anwesend","en":"present","ru":"присутствующий","vi":"hiện tại","fa":"حاضر","examples":[{"de":"Bei der Sitzung waren alle Mitglieder anwesend.","en":"All members were present at the meeting.","ru":"На заседании присутствовали все члены.","vi":"Tất cả các thành viên đều có mặt tại cuộc họp.","fa":"همه اعضا در جلسه حضور داشتند."},{"de":"Der Lehrer prüft zu Beginn der Stunde, wer anwesend ist.","en":"The teacher checks at the beginning of the lesson who is present.","ru":"Учитель в начале урока проверяет, кто присутствует.","vi":"Khi bắt đầu bài học, giáo viên kiểm tra xem ai có mặt.","fa":"در ابتدای درس، معلم بررسی می کند که چه کسی حاضر است."}]},{"word":"anzeigen","en":"to display, indicate; to report (to police)","ru":"показывать, отображать; заявлять (в полицию)","vi":"hiển thị","fa":"نشان می دهد","examples":[{"de":"Das Thermometer zeigt 25 Grad an.","en":"The thermometer shows 25 degrees.","ru":"Термометр показывает 25 градусов.","vi":"Nhiệt kế hiển thị 25 độ.","fa":"دماسنج 25 درجه را نشان می دهد."},{"de":"Sie hat den Diebstahl bei der Polizei angezeigt.","en":"She reported the theft to the police.","ru":"Она заявила о краже в полицию.","vi":"Cô đã báo cáo vụ trộm cho cảnh sát.","fa":"دزدی را به پلیس گزارش داد."}]},{"word":"die Anziehungskraft","en":"force of attraction, gravity","ru":"сила притяжения, притяжение","vi":"sự hấp dẫn","fa":"جاذبه","examples":[{"de":"Die Anziehungskraft der Erde hält uns am Boden.","en":"The earth's force of attraction keeps us on the ground.","ru":"Сила притяжения Земли удерживает нас на земле.","vi":"Lực hấp dẫn của trái đất giữ chúng ta ở trên mặt đất.","fa":"کشش گرانشی زمین ما را روی زمین نگه می دارد."},{"de":"Magnete haben eine starke Anziehungskraft.","en":"Magnets have a strong force of attraction.","ru":"У магнитов сильное притяжение.","vi":"Nam châm có lực hút rất mạnh.","fa":"آهنرباها جاذبه قوی دارند."},{"de":"Der Mond übt eine Anziehungskraft auf die Meere aus.","en":"The moon exerts a force of attraction on the seas.","ru":"Луна оказывает притяжение на моря.","vi":"Mặt trăng tạo ra lực hấp dẫn trên biển.","fa":"ماه یک کشش گرانشی بر دریاها اعمال می کند."}]},{"word":"der Anzug","en":"suit","ru":"костюм","vi":"bộ đồ","fa":"کت و شلوار","examples":[{"de":"Er trägt einen dunklen Anzug zur Hochzeit.","en":"He wears a dark suit to the wedding.","ru":"Он надевает тёмный костюм на свадьбу.","vi":"Anh ấy mặc một bộ đồ tối màu đến đám cưới.","fa":"او برای عروسی کت و شلوار تیره می پوشد."},{"de":"Ich muss mir einen neuen Anzug für das Vorstellungsgespräch kaufen.","en":"I need to buy a new suit for the job interview.","ru":"Мне нужно купить новый костюм для собеседования.","vi":"Tôi phải mua một bộ đồ mới cho cuộc phỏng vấn.","fa":"برای مصاحبه باید کت و شلوار جدید بخرم."}]},{"word":"das Apartment","en":"apartment","ru":"квартира, апартаменты","vi":"căn hộ","fa":"آپارتمان","examples":[{"de":"Sie wohnt in einem kleinen Apartment im Stadtzentrum.","en":"She lives in a small apartment in the city center.","ru":"Она живёт в маленькой квартире в центре города.","vi":"Cô sống trong một căn hộ nhỏ ở trung tâm thành phố.","fa":"او در یک آپارتمان کوچک در مرکز شهر زندگی می کند."},{"de":"Wir mieten ein Apartment für unseren Urlaub.","en":"We are renting an apartment for our vacation.","ru":"Мы снимаем квартиру на время отпуска.","vi":"Chúng tôi thuê một căn hộ cho kỳ nghỉ của chúng tôi.","fa":"ما یک آپارتمان برای تعطیلات خود اجاره می کنیم."}]},{"word":"der Apfel","en":"apple","ru":"яблоко","vi":"quả táo","fa":"سیب","examples":[{"de":"Ich esse jeden Morgen einen Apfel.","en":"I eat an apple every morning.","ru":"Я ем яблоко каждое утро.","vi":"Tôi ăn một quả táo vào mỗi buổi sáng.","fa":"من هر روز صبح یک سیب می خورم."},{"de":"Der Apfel schmeckt süß und saftig.","en":"The apple tastes sweet and juicy.","ru":"Яблоко на вкус сладкое и сочное.","vi":"Táo có vị ngọt và mọng nước.","fa":"طعم سیب شیرین و آبدار است."}]},{"word":"die Apotheke","en":"pharmacy","ru":"аптека","vi":"hiệu thuốc","fa":"داروخانه","examples":[{"de":"Ich hole meine Medikamente in der Apotheke ab.","en":"I pick up my medication at the pharmacy.","ru":"Я забираю свои лекарства в аптеке.","vi":"Tôi lấy thuốc từ hiệu thuốc.","fa":"من داروهایم را از داروخانه می گیرم."},{"de":"Die Apotheke hat auch am Wochenende geöffnet.","en":"The pharmacy is open on weekends too.","ru":"Аптека открыта и по выходным.","vi":"Hiệu thuốc cũng mở cửa vào cuối tuần.","fa":"این داروخانه در روزهای آخر هفته نیز باز است."}]},{"word":"der Apparat","en":"apparatus, device","ru":"аппарат","vi":"bộ máy","fa":"دستگاه","examples":[{"de":"Der Arzt untersucht mich mit einem speziellen Apparat.","en":"The doctor examines me with a special device.","ru":"Врач осматривает меня с помощью специального аппарата.","vi":"Bác sĩ khám cho tôi bằng một thiết bị đặc biệt.","fa":"دکتر با دستگاه مخصوص معاینه ام می کند."},{"de":"Bleiben Sie bitte am Apparat, ich verbinde Sie.","en":"Please stay on the line, I'll connect you.","ru":"Пожалуйста, оставайтесь на линии, я вас соединю.","vi":"Xin vui lòng giữ máy và tôi sẽ nối máy cho bạn.","fa":"لطفا در خط بمانید و من شما را وصل خواهم کرد."}]},{"word":"der Appetit","en":"appetite","ru":"аппетит","vi":"sự thèm ăn","fa":"اشتها","examples":[{"de":"Guten Appetit!","en":"Enjoy your meal!","ru":"Приятного аппетита!","vi":"Chúc bạn ngon miệng!","fa":"اشتهای مبارک!"},{"de":"Nach dem langen Spaziergang habe ich großen Appetit.","en":"After the long walk I have a big appetite.","ru":"После долгой прогулки у меня отличный аппетит.","vi":"Sau chuyến đi bộ dài, tôi cảm thấy thèm ăn.","fa":"بعد از پیاده روی طولانی اشتهای زیادی دارم."}]},{"word":"der Applaus","en":"applause","ru":"аплодисменты","vi":"tiếng vỗ tay","fa":"تشویق","examples":[{"de":"Nach dem Tanz brach lauter Applaus aus.","en":"After the dance loud applause broke out.","ru":"После танца раздались громкие аплодисменты.","vi":"Sau điệu múa là những tràng pháo tay vang dội.","fa":"بعد از رقص تشویق شدیدی شنیده شد."},{"de":"Der Applaus wollte gar nicht mehr aufhören.","en":"The applause simply would not stop.","ru":"Аплодисменты просто не смолкали.","vi":"Tiếng vỗ tay không muốn dừng lại.","fa":"تشویق نمی خواست قطع شود."},{"de":"Sie verdiente sich den Applaus mit einer perfekten Vorstellung.","en":"She earned the applause with a perfect show.","ru":"Она заслужила аплодисменты безупречным выступлением.","vi":"Cô đã nhận được những tràng pháo tay với màn trình diễn hoàn hảo.","fa":"او با یک اجرای بی نقص مورد تشویق قرار گرفت."}]},{"word":"die Aprikose","en":"apricot","ru":"абрикос","vi":"quả mơ","fa":"زردآلو","examples":[{"de":"Die Aprikosen sind im Sommer besonders süß.","en":"Apricots are especially sweet in summer.","ru":"Абрикосы особенно сладкие летом.","vi":"Quả mơ đặc biệt ngọt vào mùa hè.","fa":"زردآلو به خصوص در تابستان شیرین است."},{"de":"Sie kauft ein Kilo Aprikosen auf dem Markt.","en":"She buys a kilo of apricots at the market.","ru":"Она покупает килограмм абрикосов на рынке.","vi":"Cô ấy mua một kg mơ ở chợ.","fa":"او یک کیلو زردآلو از بازار می خرد."}]},{"word":"arbeiten","en":"to work","ru":"работать","vi":"làm việc","fa":"کار کردن","examples":[{"de":"Er arbeitet seit fünf Jahren in dieser Firma.","en":"He has been working at this company for five years.","ru":"Он работает в этой фирме уже пять лет.","vi":"Anh ấy đã làm việc ở công ty này được 5 năm.","fa":"او پنج سال است که در این شرکت کار می کند."},{"de":"Ich arbeite jeden Tag von acht bis vier.","en":"I work every day from eight to four.","ru":"Я работаю каждый день с восьми до четырёх.","vi":"Tôi làm việc từ tám đến bốn giờ mỗi ngày.","fa":"من هر روز از هشت تا چهار کار می کنم."}]},{"word":"der Arbeiter","en":"worker (male)","ru":"рабочий (м.)","vi":"công nhân","fa":"کارگر","examples":[{"de":"Die Arbeiter haben heute eine Pause gemacht.","en":"The workers took a break today.","ru":"Рабочие сегодня сделали перерыв.","vi":"Hôm nay công nhân được nghỉ.","fa":"کارگران امروز استراحت کردند."},{"de":"In dieser Fabrik arbeiten viele Arbeiter.","en":"Many workers work in this factory.","ru":"На этом заводе работает много рабочих.","vi":"Nhiều công nhân làm việc trong nhà máy này.","fa":"کارگران زیادی در این کارخانه کار می کنند."},{"de":"Der Arbeiter trägt einen Helm aus Sicherheitsgründen.","en":"The worker wears a helmet for safety reasons.","ru":"Рабочий носит каску из соображений безопасности.","vi":"Công nhân đội mũ bảo hiểm vì lý do an toàn.","fa":"کارگر به دلایل ایمنی از کلاه ایمنی استفاده می کند."}]},{"word":"die Arbeiterin","en":"worker (female)","ru":"рабочая (ж.)","vi":"công nhân","fa":"کارگر","examples":[{"de":"Die Arbeiterin steht jeden Morgen früh auf.","en":"The worker gets up early every morning.","ru":"Рабочая каждое утро встаёт рано.","vi":"Người công nhân dậy sớm vào mỗi buổi sáng.","fa":"کارگر هر روز صبح زود بیدار می شود."},{"de":"Jede Arbeiterin bekommt einen festen Lohn.","en":"Every worker receives a fixed wage.","ru":"Каждая рабочая получает фиксированную зарплату.","vi":"Mỗi công nhân đều nhận được một mức lương cố định.","fa":"هر کارگر مزد ثابتی دریافت می کند."},{"de":"Die Arbeiterin hat sich über die langen Schichten beschwert.","en":"The worker complained about the long shifts.","ru":"Рабочая пожаловалась на долгие смены.","vi":"Người công nhân phàn nàn về ca làm việc dài.","fa":"کارگر از شیفت های طولانی شاکی بود."}]},{"word":"der Arbeitgeber","en":"employer","ru":"работодатель","vi":"người sử dụng lao động","fa":"کارفرما","examples":[{"de":"Mein Arbeitgeber bietet flexible Arbeitszeiten an.","en":"My employer offers flexible working hours.","ru":"Мой работодатель предлагает гибкий график работы.","vi":"Chủ lao động của tôi đưa ra giờ làm việc linh hoạt.","fa":"کارفرمای من ساعات کاری انعطاف پذیری را ارائه می دهد."},{"de":"Der Arbeitgeber muss sich an das Gesetz halten.","en":"The employer has to comply with the law.","ru":"Работодатель обязан соблюдать закон.","vi":"Người sử dụng lao động phải tuân thủ pháp luật.","fa":"کارفرما باید قانون را رعایت کند."}]},{"word":"der Arbeitnehmer","en":"employee","ru":"работник; сотрудник","vi":"nhân viên","fa":"کارمند","examples":[{"de":"Jeder Arbeitnehmer hat ein Recht auf Urlaub.","en":"Every employee has a right to holiday.","ru":"Каждый работник имеет право на отпуск.","vi":"Mọi nhân viên đều có quyền nghỉ phép.","fa":"هر کارمند حق مرخصی دارد."},{"de":"Die Arbeitnehmer fordern höhere Löhne.","en":"The employees are demanding higher wages.","ru":"Работники требуют повышения зарплаты.","vi":"Công nhân đang đòi hỏi mức lương cao hơn.","fa":"کارگران خواهان افزایش دستمزد هستند."}]},{"word":"das Arbeitnehmerrecht","en":"employee right","ru":"право работника (наёмного)","vi":"luật lao động","fa":"قانون کارمندی","examples":[{"de":"Jeder sollte sein Arbeitnehmerrecht kennen.","en":"Everyone should know their employee rights.","ru":"Каждому следует знать своё право работника.","vi":"Mọi người nên biết quyền làm việc của mình.","fa":"همه باید حقوق شغلی خود را بدانند."},{"de":"Das Arbeitnehmerrecht schützt dich vor unfairer Kündigung.","en":"Employee rights protect you against unfair dismissal.","ru":"Право работника защищает тебя от несправедливого увольнения.","vi":"Luật lao động bảo vệ bạn khỏi bị sa thải không công bằng.","fa":"قانون کارمندی شما را از اخراج ناعادلانه محافظت می کند."},{"de":"Die Gewerkschaft kämpft für ein besseres Arbeitnehmerrecht.","en":"The union fights for better employee rights.","ru":"Профсоюз борется за лучшие права работников.","vi":"Công đoàn đang đấu tranh để có được quyền lợi tốt hơn cho người lao động.","fa":"اتحادیه برای حقوق بهتر کارمندان مبارزه می کند."}]},{"word":"der Arbeitsablauf","en":"workflow, work process","ru":"рабочий процесс, ход работы","vi":"quy trình làm việc","fa":"گردش کار","examples":[{"de":"Der neue Chef hat den gesamten Arbeitsablauf verändert.","en":"The new boss has changed the entire workflow.","ru":"Новый начальник изменил весь рабочий процесс.","vi":"Sếp mới đã thay đổi toàn bộ quy trình làm việc.","fa":"رئیس جدید کل گردش کار را تغییر داده است."},{"de":"Ein klarer Arbeitsablauf spart Zeit und Nerven.","en":"A clear workflow saves time and stress.","ru":"Чёткий рабочий процесс экономит время и нервы.","vi":"Một quy trình làm việc rõ ràng giúp tiết kiệm thời gian và thần kinh.","fa":"گردش کار واضح باعث صرفه جویی در زمان و اعصاب می شود."},{"de":"Störungen unterbrechen ständig unseren Arbeitsablauf.","en":"Disruptions constantly interrupt our workflow.","ru":"Помехи постоянно прерывают наш рабочий процесс.","vi":"Những xáo trộn liên tục làm gián đoạn tiến trình công việc của chúng tôi.","fa":"اختلالات دائماً جریان کار ما را مختل می کند."}]},{"word":"die Arbeitserlaubnis","en":"work permit","ru":"разрешение на работу","vi":"giấy phép làm việc","fa":"مجوز کار","examples":[{"de":"Ohne Arbeitserlaubnis darfst du hier nicht arbeiten.","en":"Without a work permit you may not work here.","ru":"Без разрешения на работу ты не имеешь права здесь работать.","vi":"Bạn không được phép làm việc ở đây nếu không có giấy phép lao động.","fa":"شما مجاز به کار در اینجا بدون مجوز کار نیستید."},{"de":"Er hat endlich seine Arbeitserlaubnis bekommen.","en":"He finally got his work permit.","ru":"Он наконец получил своё разрешение на работу.","vi":"Cuối cùng anh ấy đã có được giấy phép làm việc.","fa":"بالاخره مجوز کارش را گرفت."},{"de":"Die Arbeitserlaubnis gilt nur für ein Jahr.","en":"The work permit is valid for only one year.","ru":"Разрешение на работу действует только один год.","vi":"Giấy phép làm việc chỉ có giá trị trong một năm.","fa":"مجوز کار فقط برای یک سال معتبر است."}]},{"word":"arbeitslos","en":"unemployed","ru":"безработный","vi":"thất nghiệp","fa":"بیکار","examples":[{"de":"Der Arbeitslose sucht seit Monaten eine Stelle.","en":"The unemployed man has been looking for a job for months.","ru":"Безработный уже месяцами ищет работу.","vi":"Người thất nghiệp đã tìm việc làm trong nhiều tháng.","fa":"این فرد بیکار ماه هاست که دنبال کار می گردد."},{"de":"Seit der Fabrik schloss, ist er arbeitslos.","en":"Since the factory closed, he has been unemployed.","ru":"С тех пор как фабрику закрыли, он безработный.","vi":"Anh ấy đã thất nghiệp kể từ khi nhà máy đóng cửa.","fa":"او از زمان تعطیلی کارخانه بیکار است."},{"de":"Viele junge Menschen in der Region sind arbeitslos.","en":"Many young people in the region are unemployed.","ru":"Многие молодые люди в регионе безработные.","vi":"Nhiều thanh niên trong khu vực đang thất nghiệp.","fa":"بسیاری از جوانان منطقه بیکار هستند."}]},{"word":"die Arbeitslosigkeit","en":"unemployment","ru":"безработица","vi":"thất nghiệp","fa":"بیکاری","examples":[{"de":"Die Arbeitslosigkeit ist in dieser Region sehr hoch.","en":"Unemployment is very high in this region.","ru":"Безработица в этом регионе очень высокая.","vi":"Tỷ lệ thất nghiệp ở khu vực này rất cao.","fa":"بیکاری در این منطقه بسیار بالاست."},{"de":"Die Regierung will die Arbeitslosigkeit bekämpfen.","en":"The government wants to combat unemployment.","ru":"Правительство хочет бороться с безработицей.","vi":"Chính phủ muốn chống lại tình trạng thất nghiệp.","fa":"دولت می خواهد با بیکاری مبارزه کند."},{"de":"Nach der Krise stieg die Arbeitslosigkeit stark an.","en":"After the crisis, unemployment rose sharply.","ru":"После кризиса безработица резко выросла.","vi":"Sau khủng hoảng, tỷ lệ thất nghiệp tăng mạnh.","fa":"پس از بحران، بیکاری به شدت افزایش یافت."}]},{"word":"die Arbeitsstelle","en":"job, place of work","ru":"рабочее место, место работы","vi":"nơi làm việc","fa":"محل کار","examples":[{"de":"Ich suche eine neue Arbeitsstelle in der Stadt.","en":"I am looking for a new job in the city.","ru":"Я ищу новое место работы в городе.","vi":"Tôi đang tìm kiếm một công việc mới ở thành phố.","fa":"دنبال کار جدید در شهر هستم."},{"de":"Meine Arbeitsstelle ist nur zehn Minuten von zu Hause entfernt.","en":"My place of work is only ten minutes from home.","ru":"Моё место работы всего в десяти минутах от дома.","vi":"Chỗ làm của tôi chỉ cách nhà mười phút.","fa":"کار من فقط ده دقیقه با خانه فاصله دارد."},{"de":"Er hat seine Arbeitsstelle nach fünf Jahren gewechselt.","en":"He changed his job after five years.","ru":"Он сменил место работы через пять лет.","vi":"Anh ấy đã thay đổi công việc của mình sau năm năm.","fa":"بعد از پنج سال شغلش را عوض کرد."}]},{"word":"die Archäologie","en":"archaeology","ru":"археология","vi":"khảo cổ học","fa":"باستان شناسی","examples":[{"de":"Dank der Archäologie wissen wir viel über antike Kulturen.","en":"Thanks to archaeology we know a great deal about ancient cultures.","ru":"Благодаря археологии мы много знаем о древних культурах.","vi":"Nhờ khảo cổ học, chúng ta biết rất nhiều về các nền văn hóa cổ xưa.","fa":"به لطف باستان شناسی، ما چیزهای زیادی در مورد فرهنگ های باستانی می دانیم."},{"de":"Sie studiert Archäologie an einer Universität in Köln.","en":"She is studying archaeology at a university in Cologne.","ru":"Она изучает археологию в университете в Кёльне.","vi":"Cô học khảo cổ học tại một trường đại học ở Cologne.","fa":"او در دانشگاهی در کلن باستان شناسی می خواند."},{"de":"Die moderne Archäologie nutzt heute viele technische Methoden.","en":"Modern archaeology nowadays uses many technical methods.","ru":"Современная археология использует сегодня множество технических методов.","vi":"Khảo cổ học hiện đại hiện nay sử dụng nhiều phương pháp kỹ thuật.","fa":"باستان شناسی مدرن اکنون از روش های فنی بسیاری استفاده می کند."}]},{"word":"der Architekt","en":"architect","ru":"архитектор","vi":"kiến trúc sư","fa":"معمار","examples":[{"de":"Der Architekt plant ein neues Bürogebäude.","en":"The architect is planning a new office building.","ru":"Архитектор проектирует новое офисное здание.","vi":"Kiến trúc sư đang lên kế hoạch xây dựng một tòa nhà văn phòng mới.","fa":"معمار در حال برنامه ریزی یک ساختمان اداری جدید است."},{"de":"Sie möchte Architektin werden und Häuser entwerfen.","en":"She wants to become an architect and design houses.","ru":"Она хочет стать архитектором и проектировать дома.","vi":"Cô muốn trở thành một kiến ​​trúc sư và thiết kế nhà cửa.","fa":"او می خواهد معمار شود و خانه ها را طراحی کند."}]},{"word":"die Architektin","en":"architect (female)","ru":"архитектор (ж.)","vi":"kiến trúc sư","fa":"معمار","examples":[{"de":"Die Architektin hat den neuen Bahnhof entworfen.","en":"The architect designed the new railway station.","ru":"Архитектор спроектировала новый вокзал.","vi":"Kiến trúc sư đã thiết kế nhà ga xe lửa mới.","fa":"معمار ایستگاه قطار جدید را طراحی کرد."},{"de":"Als Architektin reist sie oft zu Baustellen.","en":"As an architect she often travels to construction sites.","ru":"Как архитектор она часто ездит на стройплощадки.","vi":"Là một kiến ​​trúc sư, cô thường xuyên đến các công trường xây dựng.","fa":"به عنوان یک معمار، او اغلب به سایت های ساختمانی سفر می کند."},{"de":"Die Architektin liebt moderne und helle Räume.","en":"The architect loves modern and bright rooms.","ru":"Архитектор любит современные и светлые помещения.","vi":"Kiến trúc sư yêu thích những căn phòng hiện đại và sáng sủa.","fa":"معمار عاشق اتاق های مدرن و روشن است."}]},{"word":"der Ärger","en":"trouble, annoyance, anger","ru":"неприятности, досада, раздражение","vi":"sự tức giận","fa":"خشم","examples":[{"de":"Mit dem alten Auto gibt es nur Ärger.","en":"The old car is nothing but trouble.","ru":"От старой машины одни неприятности.","vi":"Với chiếc xe cũ chỉ có rắc rối.","fa":"با ماشین قدیمی فقط مشکل وجود دارد."},{"de":"Sein Gesicht zeigte deutlichen Ärger.","en":"His face showed clear annoyance.","ru":"На его лице читалась явная досада.","vi":"Khuôn mặt anh hiện rõ sự tức giận.","fa":"چهره اش خشم آشکاری را نشان می داد."},{"de":"Ich will keinen Ärger mit den Nachbarn.","en":"I don't want any trouble with the neighbours.","ru":"Я не хочу неприятностей с соседями.","vi":"Tôi không muốn gặp rắc rối với hàng xóm.","fa":"من هیچ مشکلی با همسایه ها نمی خواهم."}]},{"word":"ärgerlich","en":"annoying; annoyed","ru":"досадный, раздражающий; раздосадованный","vi":"khó chịu","fa":"آزار دهنده","examples":[{"de":"Es ist ärgerlich, dass der Zug schon wieder Verspätung hat.","en":"It is annoying that the train is delayed yet again.","ru":"Досадно, что поезд снова опаздывает.","vi":"Thật khó chịu khi tàu lại trễ.","fa":"آزار دهنده است که قطار دوباره دیر می شود."},{"de":"Sie war ärgerlich über seine Bemerkung.","en":"She was annoyed about his remark.","ru":"Она была раздосадована его замечанием.","vi":"Cô khó chịu vì lời nhận xét của anh.","fa":"از اظهار نظر او ناراحت شد."},{"de":"So ein ärgerlicher Fehler kostet uns viel Zeit.","en":"Such an annoying mistake costs us a lot of time.","ru":"Такая досадная ошибка стоит нам много времени.","vi":"Một sai lầm khó chịu như vậy khiến chúng tôi tốn rất nhiều thời gian.","fa":"چنین اشتباه آزاردهنده ای برای ما هزینه زیادی دارد."}]},{"word":"das Argument","en":"argument","ru":"аргумент, довод","vi":"lập luận","fa":"استدلال","examples":[{"de":"Sie brachte ein überzeugendes Argument in die Debatte ein.","en":"She brought a convincing argument into the debate.","ru":"Она привела в дискуссию убедительный аргумент.","vi":"Cô đã đưa ra một lập luận thuyết phục cho cuộc tranh luận.","fa":"او استدلال قانع کننده ای را به مناظره آورد."},{"de":"Dein Argument hat mich nicht wirklich überzeugt.","en":"Your argument did not really convince me.","ru":"Твой аргумент меня не очень убедил.","vi":"Lập luận của bạn không thực sự thuyết phục được tôi.","fa":"استدلال شما واقعاً من را قانع نکرد."},{"de":"Das stärkste Argument für den Plan sind die niedrigen Kosten.","en":"The strongest argument for the plan is the low cost.","ru":"Самый сильный аргумент в пользу плана — низкие расходы.","vi":"Lập luận mạnh mẽ nhất cho kế hoạch này là chi phí thấp.","fa":"قوی ترین استدلال برای این طرح هزینه پایین آن است."}]},{"word":"arm","en":"poor","ru":"бедный","vi":"nghèo nàn","fa":"فقیر","examples":[{"de":"Die Familie war früher sehr arm.","en":"The family used to be very poor.","ru":"Раньше семья была очень бедной.","vi":"Gia đình ngày xưa rất nghèo.","fa":"خانواده قبلاً بسیار فقیر بودند."},{"de":"Viele Menschen in dieser Region sind arm.","en":"Many people in this region are poor.","ru":"Многие люди в этом регионе бедны.","vi":"Nhiều người ở vùng này nghèo.","fa":"بسیاری از مردم این منطقه فقیر هستند."}]},{"word":"der Arm","en":"arm","ru":"рука (от плеча до кисти)","vi":"cánh tay","fa":"بازو","examples":[{"de":"Er hat sich beim Fußball den Arm gebrochen.","en":"He broke his arm playing football.","ru":"Он сломал руку, играя в футбол.","vi":"Anh ấy bị gãy tay khi chơi bóng đá.","fa":"او در بازی فوتبال دستش شکست."},{"de":"Sie trägt das Kind auf dem Arm.","en":"She carries the child in her arms.","ru":"Она несёт ребёнка на руках.","vi":"Cô bế đứa trẻ trên tay.","fa":"او کودک را در آغوش می گیرد."}]},{"word":"die Armut","en":"poverty","ru":"бедность, нищета","vi":"sự nghèo đói","fa":"فقر","examples":[{"de":"Armut ist in vielen Ländern ein großes Problem.","en":"Poverty is a serious problem in many countries.","ru":"Бедность — серьёзная проблема во многих странах.","vi":"Nghèo đói là một vấn đề lớn ở nhiều quốc gia.","fa":"فقر یک مشکل بزرگ در بسیاری از کشورها است."},{"de":"Der Staat versucht, die Armut zu bekämpfen.","en":"The state tries to combat poverty.","ru":"Государство пытается бороться с бедностью.","vi":"Nhà nước đang cố gắng chống lại nghèo đói.","fa":"دولت تلاش می کند با فقر مبارزه کند."},{"de":"Bildung kann ein Weg aus der Armut sein.","en":"Education can be a way out of poverty.","ru":"Образование может стать выходом из бедности.","vi":"Giáo dục có thể là một cách thoát nghèo.","fa":"آموزش می تواند راهی برای رهایی از فقر باشد."}]},{"word":"das Aroma","en":"aroma","ru":"аромат, запах","vi":"hương thơm","fa":"عطر","examples":[{"de":"Der Kaffee verströmt ein kräftiges Aroma in der ganzen Küche.","en":"The coffee gives off a strong aroma throughout the whole kitchen.","ru":"Кофе разносит крепкий аромат по всей кухне.","vi":"Cà phê tỏa hương thơm nồng nàn khắp căn bếp.","fa":"قهوه عطری قوی در سراسر آشپزخانه پخش می کند."},{"de":"Das Aroma der frisch gebackenen Brötchen lockte alle in die Küche.","en":"The aroma of the freshly baked rolls drew everyone into the kitchen.","ru":"Аромат свежеиспечённых булочек заманил всех на кухню.","vi":"Mùi thơm của những ổ bánh cuốn mới nướng đã thu hút mọi người vào bếp.","fa":"عطر رول های تازه پخته شده همه را به آشپزخانه کشاند."},{"de":"Dieser Tee hat ein feines Aroma von Zitrone und Minze.","en":"This tea has a delicate aroma of lemon and mint.","ru":"У этого чая тонкий аромат лимона и мяты.","vi":"Trà này có mùi thơm tinh tế của chanh và bạc hà.","fa":"این چای دارای رایحه لطیف لیمو و نعناع است."}]},{"word":"die Art","en":"kind, type; way, manner","ru":"вид, тип; способ","vi":"loại","fa":"نوع","examples":[{"de":"Das ist eine besondere Art von Musik.","en":"That is a special kind of music.","ru":"Это особый вид музыки.","vi":"Đây là một loại âm nhạc đặc biệt.","fa":"این یک نوع موسیقی خاص است."},{"de":"Er löst Probleme auf seine eigene Art.","en":"He solves problems in his own way.","ru":"Он решает проблемы по-своему.","vi":"Anh ấy giải quyết vấn đề theo cách riêng của mình.","fa":"او مشکلات را به روش خودش حل می کند."}]},{"word":"die Artenvielfalt","en":"biodiversity","ru":"биоразнообразие, разнообразие видов","vi":"sự đa dạng sinh học","fa":"تنوع زیستی","examples":[{"de":"Im Regenwald ist die Artenvielfalt besonders groß.","en":"In the rainforest the biodiversity is especially great.","ru":"В тропическом лесу биоразнообразие особенно велико.","vi":"Sự đa dạng của các loài đặc biệt cao trong rừng nhiệt đới.","fa":"تنوع گونه ها به ویژه در جنگل های بارانی زیاد است."},{"de":"Pestizide bedrohen die Artenvielfalt auf den Feldern.","en":"Pesticides threaten biodiversity in the fields.","ru":"Пестициды угрожают биоразнообразию на полях.","vi":"Thuốc trừ sâu đe dọa đa dạng sinh học trên đồng ruộng.","fa":"آفت کش ها تنوع زیستی در مزارع را تهدید می کنند."},{"de":"Wir müssen die Artenvielfalt für die Zukunft erhalten.","en":"We must preserve biodiversity for the future.","ru":"Мы должны сохранить биоразнообразие для будущего.","vi":"Chúng ta phải bảo tồn đa dạng sinh học cho tương lai.","fa":"ما باید تنوع زیستی را برای آینده حفظ کنیم."}]},{"word":"der Artikel","en":"article; item","ru":"статья; товар","vi":"bài báo","fa":"مقاله","examples":[{"de":"Ich habe einen interessanten Artikel in der Zeitung gelesen.","en":"I read an interesting article in the newspaper.","ru":"Я прочитал интересную статью в газете.","vi":"Tôi đọc được một bài viết thú vị trên báo.","fa":"مقاله جالبی در روزنامه خواندم."},{"de":"Dieser Artikel ist im Moment leider nicht vorrätig.","en":"This item is unfortunately out of stock at the moment.","ru":"К сожалению, этого товара сейчас нет в наличии.","vi":"Thật không may, mặt hàng này hiện đã hết hàng.","fa":"متاسفانه این کالا در حال حاضر موجود نیست."}]},{"word":"der Arzt","en":"doctor","ru":"врач","vi":"bác sĩ","fa":"دکتر","examples":[{"de":"Ich habe morgen einen Termin beim Arzt.","en":"I have an appointment with the doctor tomorrow.","ru":"Завтра у меня приём у врача.","vi":"Tôi có hẹn với bác sĩ vào ngày mai.","fa":"فردا با دکتر وقت دارم"},{"de":"Der Arzt untersucht den Patienten gründlich.","en":"The doctor examines the patient thoroughly.","ru":"Врач тщательно осматривает пациента.","vi":"Bác sĩ khám bệnh nhân kỹ lưỡng.","fa":"پزشک بیمار را به طور کامل معاینه می کند."}]},{"word":"die Ärztin","en":"doctor, physician (female)","ru":"врач, докторша (жен.)","vi":"bác sĩ","fa":"دکتر","examples":[{"de":"Meine Ärztin hat mir Ruhe verordnet.","en":"My doctor prescribed me rest.","ru":"Моя врач прописала мне покой.","vi":"Bác sĩ kê đơn cho tôi nghỉ ngơi.","fa":"دکترم برایم استراحت تجویز کرد."},{"de":"Sie arbeitet als Ärztin im Krankenhaus.","en":"She works as a doctor in the hospital.","ru":"Она работает врачом в больнице.","vi":"Cô ấy làm việc như một bác sĩ trong bệnh viện.","fa":"او به عنوان پزشک در بیمارستان کار می کند."},{"de":"Die Ärztin untersuchte den Patienten sorgfältig.","en":"The doctor examined the patient carefully.","ru":"Врач тщательно осмотрела пациента.","vi":"Bác sĩ khám bệnh nhân cẩn thận.","fa":"دکتر بیمار را به دقت معاینه کرد."}]},{"word":"der Asteroid","en":"asteroid","ru":"астероид","vi":"tiểu hành tinh","fa":"the asteroid","examples":[{"de":"Ein großer Asteroid flog dicht an der Erde vorbei.","en":"A large asteroid flew close past the Earth.","ru":"Большой астероид пролетел вплотную к Земле.","vi":"Một tiểu hành tinh lớn bay đến gần Trái đất.","fa":"یک سیارک بزرگ به زمین نزدیک شد."},{"de":"Zwischen Mars und Jupiter liegt ein Gürtel aus Asteroiden.","en":"Between Mars and Jupiter there is a belt of asteroids.","ru":"Между Марсом и Юпитером находится пояс астероидов.","vi":"Có một vành đai tiểu hành tinh nằm giữa Sao Hỏa và Sao Mộc.","fa":"کمربند سیارکی بین مریخ و مشتری وجود دارد."},{"de":"Wissenschaftler beobachten gefährliche Asteroiden genau.","en":"Scientists closely observe dangerous asteroids.","ru":"Учёные внимательно следят за опасными астероидами.","vi":"Các nhà khoa học đang theo dõi chặt chẽ các tiểu hành tinh nguy hiểm.","fa":"دانشمندان از نزدیک سیارک های خطرناک را زیر نظر دارند."}]},{"word":"die Astrologie","en":"astrology","ru":"астрология","vi":"chiêm tinh học","fa":"طالع بینی","examples":[{"de":"Im Gegensatz zur Astronomie ist die Astrologie keine Wissenschaft.","en":"Unlike astronomy, astrology is not a science.","ru":"В отличие от астрономии, астрология не является наукой.","vi":"Không giống như thiên văn học, chiêm tinh học không phải là một môn khoa học.","fa":"بر خلاف نجوم، طالع بینی یک علم نیست."},{"de":"Viele Menschen lesen jeden Tag ihr Horoskop und glauben an die Astrologie.","en":"Many people read their horoscope every day and believe in astrology.","ru":"Многие люди каждый день читают свой гороскоп и верят в астрологию.","vi":"Nhiều người đọc tử vi hàng ngày và tin vào chiêm tinh học.","fa":"بسیاری از مردم هر روز فال خود را می خوانند و به طالع بینی اعتقاد دارند."},{"de":"Die Astrologie ordnet jedem Sternzeichen bestimmte Eigenschaften zu.","en":"Astrology assigns certain traits to each star sign.","ru":"Астрология приписывает каждому знаку зодиака определённые качества.","vi":"Chiêm tinh gán những đặc điểm nhất định cho từng cung hoàng đạo.","fa":"طالع بینی ویژگی های خاصی را به هر علامت زودیاک اختصاص می دهد."}]},{"word":"der Astronom","en":"astronomer","ru":"астроном","vi":"nhà thiên văn học","fa":"the astronomer","examples":[{"de":"Der Astronom entdeckte einen neuen Stern.","en":"The astronomer discovered a new star.","ru":"Астроном открыл новую звезду.","vi":"Nhà thiên văn học đã phát hiện ra một ngôi sao mới.","fa":"ستاره شناس ستاره جدیدی کشف کرد."},{"de":"Ein Astronom verbringt viele Nächte am Teleskop.","en":"An astronomer spends many nights at the telescope.","ru":"Астроном проводит много ночей у телескопа.","vi":"Một nhà thiên văn học dành nhiều đêm ở kính thiên văn.","fa":"یک ستاره شناس شب های زیادی را در تلسکوپ می گذراند."},{"de":"Berühmte Astronomen veränderten unser Bild vom Universum.","en":"Famous astronomers changed our picture of the universe.","ru":"Знаменитые астрономы изменили наше представление о Вселенной.","vi":"Các nhà thiên văn học nổi tiếng đã thay đổi quan điểm của chúng ta về vũ trụ.","fa":"ستاره شناسان مشهور دیدگاه ما را نسبت به جهان تغییر دادند."}]},{"word":"die Astronomie","en":"astronomy","ru":"астрономия","vi":"thiên văn học","fa":"نجوم","examples":[{"de":"Die Astronomie erforscht die Sterne und Planeten am Himmel.","en":"Astronomy studies the stars and planets in the sky.","ru":"Астрономия изучает звёзды и планеты на небе.","vi":"Thiên văn học nghiên cứu các ngôi sao và hành tinh trên bầu trời.","fa":"ستاره شناسی ستارگان و سیارات آسمان را مطالعه می کند."},{"de":"Schon als Kind interessierte er sich für Astronomie.","en":"Even as a child he was interested in astronomy.","ru":"Ещё в детстве он интересовался астрономией.","vi":"Ông quan tâm đến thiên văn học khi còn nhỏ.","fa":"او از کودکی به نجوم علاقه داشت."},{"de":"An der Universität kann man Astronomie studieren.","en":"You can study astronomy at university.","ru":"В университете можно изучать астрономию.","vi":"Bạn có thể học thiên văn học ở trường đại học.","fa":"شما می توانید در دانشگاه نجوم بخوانید."}]},{"word":"das Asyl","en":"asylum","ru":"убежище","vi":"trại tị nạn","fa":"پناهندگی","examples":[{"de":"Der Flüchtling beantragt Asyl in Deutschland.","en":"The refugee applies for asylum in Germany.","ru":"Беженец подаёт заявление на убежище в Германии.","vi":"Người tị nạn nộp đơn xin tị nạn ở Đức.","fa":"این پناهنده در آلمان درخواست پناهندگی می کند."},{"de":"Viele Menschen suchen politisches Asyl in Europa.","en":"Many people seek political asylum in Europe.","ru":"Многие люди ищут политическое убежище в Европе.","vi":"Nhiều người đang xin tị nạn chính trị ở châu Âu.","fa":"بسیاری از مردم به دنبال پناهندگی سیاسی در اروپا هستند."}]},{"word":"der Atemzug","en":"breath (single)","ru":"вдох (как единичный акт дыхания)","vi":"hơi thở","fa":"نفس","examples":[{"de":"Halte die Stellung für drei tiefe Atemzüge.","en":"Hold the pose for three deep breaths.","ru":"Удерживай позу на три глубоких вдоха.","vi":"Giữ tư thế trong ba hơi thở sâu.","fa":"این حالت را برای سه نفس عمیق نگه دارید."},{"de":"Mit jedem Atemzug wirst du ruhiger.","en":"With every breath you become calmer.","ru":"С каждым вдохом ты становишься спокойнее.","vi":"Với mỗi hơi thở bạn trở nên bình tĩnh hơn.","fa":"با هر نفس آرام تر میشوی"},{"de":"Sie zählte die Atemzüge während der Meditation.","en":"She counted the breaths during the meditation.","ru":"Она считала вдохи во время медитации.","vi":"Cô đếm hơi thở trong khi thiền định.","fa":"او در حین مدیتیشن نفس ها را می شمرد."}]},{"word":"atmen","en":"to breathe","ru":"дышать","vi":"thở","fa":"نفس بکش","examples":[{"de":"Nach dem Lauf musste er tief atmen.","en":"After the run he had to breathe deeply.","ru":"После пробежки ему нужно было глубоко дышать.","vi":"Sau khi chạy anh phải thở thật sâu.","fa":"بعد از دویدن مجبور شد نفس عمیقی بکشد."},{"de":"Atmen Sie ruhig ein und aus.","en":"Breathe in and out calmly.","ru":"Спокойно вдыхайте и выдыхайте.","vi":"Thở vào và thở ra một cách bình tĩnh.","fa":"با آرامش نفس به داخل و خارج کنید."}]},{"word":"die Atmosphäre","en":"atmosphere","ru":"атмосфера","vi":"bầu không khí","fa":"جو","examples":[{"de":"Die Atmosphäre der Erde schützt uns vor der Strahlung der Sonne.","en":"The Earth's atmosphere protects us from the sun's radiation.","ru":"Атмосфера Земли защищает нас от солнечного излучения.","vi":"Bầu khí quyển của Trái đất bảo vệ chúng ta khỏi bức xạ của mặt trời.","fa":"جو زمین از ما در برابر تابش خورشید محافظت می کند."},{"de":"In großer Höhe wird die Atmosphäre immer dünner.","en":"At high altitude the atmosphere becomes ever thinner.","ru":"На большой высоте атмосфера становится всё разреженнее.","vi":"Ở độ cao lớn, bầu không khí ngày càng trở nên loãng hơn.","fa":"در ارتفاعات بالا جو به طور فزاینده ای نازک تر می شود."},{"de":"Das Restaurant hatte eine sehr gemütliche Atmosphäre.","en":"The restaurant had a very cosy atmosphere.","ru":"В ресторане была очень уютная атмосфера.","vi":"Nhà hàng có một bầu không khí rất ấm cúng.","fa":"فضای رستوران بسیار دنج بود."}]},{"word":"die Atmung","en":"breathing, respiration","ru":"дыхание","vi":"hơi thở","fa":"تنفس","examples":[{"de":"Im Yoga steht die ruhige, tiefe Atmung im Mittelpunkt.","en":"In yoga, calm, deep breathing is at the centre.","ru":"В йоге в центре внимания находится спокойное, глубокое дыхание.","vi":"Trong yoga, trọng tâm là hít thở sâu và bình tĩnh.","fa":"در یوگا، تمرکز بر تنفس آرام و عمیق است."},{"de":"Nach dem Lauf brauchte er einige Minuten, bis sich seine Atmung beruhigte.","en":"After the run he needed a few minutes for his breathing to settle.","ru":"После пробежки ему понадобилось несколько минут, чтобы дыхание успокоилось.","vi":"Sau khi chạy, phải mất vài phút anh mới bình tĩnh lại được.","fa":"پس از دویدن، چند دقیقه طول کشید تا نفس هایش آرام شود."},{"de":"Eine flache Atmung kann ein Zeichen von Stress sein.","en":"Shallow breathing can be a sign of stress.","ru":"Поверхностное дыхание может быть признаком стресса.","vi":"Thở nông có thể là dấu hiệu của sự căng thẳng.","fa":"تنفس کم عمق می تواند نشانه استرس باشد."}]},{"word":"das Atom","en":"atom","ru":"атом","vi":"nguyên tử","fa":"اتم","examples":[{"de":"Jedes Atom besteht aus einem Kern und mehreren Elektronen.","en":"Every atom consists of a nucleus and several electrons.","ru":"Каждый атом состоит из ядра и нескольких электронов.","vi":"Mỗi nguyên tử bao gồm một hạt nhân và một số electron.","fa":"هر اتم از یک هسته و چندین الکترون تشکیل شده است."},{"de":"Bei einer Kernspaltung wird ein Atom in zwei kleinere Teile gespalten.","en":"During nuclear fission, an atom is split into two smaller parts.","ru":"При делении ядра атом расщепляется на две меньшие части.","vi":"Trong quá trình phân hạch hạt nhân, một nguyên tử bị tách thành hai phần nhỏ hơn.","fa":"در طی شکافت هسته ای، یک اتم به دو قسمت کوچکتر تقسیم می شود."},{"de":"Ein einzelnes Atom ist viel zu klein, um es mit bloßem Auge zu sehen.","en":"A single atom is far too small to see with the naked eye.","ru":"Отдельный атом слишком мал, чтобы увидеть его невооружённым глазом.","vi":"Một nguyên tử quá nhỏ để có thể nhìn thấy bằng mắt thường.","fa":"یک اتم بسیار کوچکتر از آن است که با چشم غیر مسلح دیده شود."}]},{"word":"der Atomkern","en":"atomic nucleus","ru":"атомное ядро","vi":"hạt nhân nguyên tử","fa":"هسته اتم","examples":[{"de":"Der Atomkern besteht aus Protonen und Neutronen.","en":"The atomic nucleus consists of protons and neutrons.","ru":"Атомное ядро состоит из протонов и нейтронов.","vi":"Hạt nhân nguyên tử bao gồm các proton và neutron.","fa":"هسته اتم از پروتون و نوترون تشکیل شده است."},{"de":"Fast die gesamte Masse steckt im Atomkern.","en":"Almost all the mass is contained in the atomic nucleus.","ru":"Почти вся масса заключена в атомном ядре.","vi":"Hầu như toàn bộ khối lượng nằm ở hạt nhân nguyên tử.","fa":"تقریباً تمام جرم در هسته اتم است."},{"de":"Der Atomkern ist im Vergleich zum Atom sehr klein.","en":"The atomic nucleus is very small compared with the atom.","ru":"Атомное ядро очень мало по сравнению с атомом.","vi":"Hạt nhân rất nhỏ so với nguyên tử.","fa":"هسته در مقایسه با اتم بسیار کوچک است."}]},{"word":"die Au","en":"water meadow, floodplain","ru":"пойма, заливной луг (у реки)","vi":"người Âu","fa":"طلا","examples":[{"de":"Hinter dem Dorf liegt eine grüne Au am Fluss.","en":"Behind the village lies a green water meadow by the river.","ru":"За деревней у реки лежит зелёный заливной луг.","vi":"Phía sau làng có đồng cỏ xanh bên dòng sông.","fa":"پشت روستا یک چمنزار سرسبز در کنار رودخانه وجود دارد."},{"de":"In der Au blühen im Frühling viele Blumen.","en":"In the floodplain many flowers bloom in spring.","ru":"Весной на пойменном лугу цветёт много цветов.","vi":"Nhiều loài hoa nở trên vùng ngập vào mùa xuân.","fa":"بسیاری از گلها در بهار در دشت سیلابی شکوفا می شوند."},{"de":"Wir machten einen Spaziergang durch die feuchte Au.","en":"We took a walk through the damp water meadow.","ru":"Мы прогулялись по влажному заливному лугу.","vi":"Chúng tôi đi dạo qua đồng cỏ ẩm ướt.","fa":"در چمنزار نمناک قدم زدیم."}]},{"word":"auch","en":"also, too","ru":"тоже, также","vi":"cũng","fa":"همچنین","examples":[{"de":"Ich mag Kaffee, aber ich trinke auch gern Tee.","en":"I like coffee, but I also like drinking tea.","ru":"Мне нравится кофе, но я также люблю пить чай.","vi":"Tôi thích cà phê nhưng tôi cũng thích uống trà.","fa":"من قهوه را دوست دارم، اما نوشیدن چای را هم دوست دارم."},{"de":"Kommst du auch zur Party?","en":"Are you coming to the party too?","ru":"Ты тоже придёшь на вечеринку?","vi":"Bạn cũng đến dự tiệc à?","fa":"آیا شما هم به مهمانی می آیید؟"}]},{"word":"auf","en":"on, onto; open","ru":"на; открыто","vi":"trên","fa":"در","examples":[{"de":"Das Buch liegt auf dem Tisch.","en":"The book is lying on the table.","ru":"Книга лежит на столе.","vi":"Cuốn sách ở trên bàn.","fa":"کتاب روی میز است."},{"de":"Die Tür ist den ganzen Tag auf.","en":"The door is open all day.","ru":"Дверь открыта весь день.","vi":"Cửa mở cả ngày.","fa":"در تمام روز باز است."}]},{"word":"auf dem Holzweg sein","en":"to be on the wrong track / mistaken","ru":"идти по ложному пути, ошибаться","vi":"đi sai đường/nhầm lẫn","fa":"در مسیر اشتباه قرار گرفتن / اشتباه کردن","examples":[{"de":"Wenn du das glaubst, bist du auf dem Holzweg.","en":"If you believe that, you're on the wrong track.","ru":"Если ты так думаешь, ты на ложном пути.","vi":"Nếu bạn tin vào điều đó thì bạn đang đi sai hướng.","fa":"اگر این را باور دارید، در مسیر اشتباهی هستید."}]},{"word":"Auf der einen Seite … auf der anderen Seite …","en":"On one side … on the other side … (weighing up)","ru":"С одной стороны … с другой стороны … (взвешивание)","vi":"Một bên… bên kia…","fa":"از یک طرف ... از طرف دیگر ...","examples":[{"de":"Auf der einen Seite spart man Zeit, auf der anderen Seite kostet es mehr.","en":"On one side you save time, on the other side it costs more.","ru":"С одной стороны экономишь время, с другой — это дороже.","vi":"Một mặt bạn tiết kiệm được thời gian nhưng mặt khác lại tốn kém hơn.","fa":"از یک طرف در زمان صرفه جویی می کنید، از طرف دیگر هزینه بیشتری دارد."}]},{"word":"auf großem Fuß leben","en":"to live large / beyond one's means","ru":"жить на широкую ногу","vi":"sống xa hoa/vượt quá khả năng của mình","fa":"بزرگ زیستن / فراتر از توان خود","examples":[{"de":"Nach dem Lottogewinn lebte er auf großem Fuß.","en":"After winning the lottery he lived large.","ru":"После выигрыша в лотерею он жил на широкую ногу.","vi":"Sau khi trúng số, anh ta sống rất xa hoa.","fa":"پس از برنده شدن در لاتاری، او در مقیاس بزرگ زندگی کرد."}]},{"word":"aufdrehen","en":"to turn on, turn up (a tap, volume)","ru":"открывать, включать на полную (кран, громкость)","vi":"bật nó lên","fa":"آن را روشن کن","examples":[{"de":"Dreh bitte das Wasser auf.","en":"Please turn the water on.","ru":"Пожалуйста, открой воду.","vi":"Hãy mở nước lên.","fa":"لطفا آب را روشن کنید"},{"de":"Er dreht die Musik laut auf.","en":"He turns the music up loud.","ru":"Он делает музыку громче.","vi":"Anh vặn nhạc to lên.","fa":"او موسیقی را با صدای بلند بلند می کند."},{"de":"Ich drehe die Heizung etwas auf.","en":"I'll turn the heating up a bit.","ru":"Я немного прибавлю отопление.","vi":"Tôi tăng nhiệt lên một chút.","fa":"حرارت را کمی زیاد می کنم."}]},{"word":"der Aufenthalt","en":"stay","ru":"пребывание","vi":"ở lại","fa":"اقامت","examples":[{"de":"Wir wünschen Ihnen einen angenehmen Aufenthalt.","en":"We wish you a pleasant stay.","ru":"Желаем вам приятного пребывания.","vi":"Chúng tôi chúc bạn một kỳ nghỉ thú vị.","fa":"اقامت خوشی را برای شما آرزومندیم."},{"de":"Der Aufenthalt in diesem Land war für mich sehr lehrreich.","en":"My stay in this country was very educational for me.","ru":"Пребывание в этой стране было для меня очень поучительным.","vi":"Thời gian ở đất nước này mang lại cho tôi rất nhiều kiến ​​thức.","fa":"اقامت من در این کشور برایم بسیار آموزشی بود."}]},{"word":"die Aufenthaltsdauer","en":"length of stay","ru":"продолжительность пребывания, срок пребывания","vi":"thời gian lưu trú","fa":"مدت اقامت","examples":[{"de":"Die Aufenthaltsdauer im Hotel beträgt fünf Nächte.","en":"The length of stay in the hotel is five nights.","ru":"Продолжительность пребывания в отеле составляет пять ночей.","vi":"Thời gian lưu trú tại khách sạn là năm đêm.","fa":"مدت اقامت در هتل پنج شب می باشد."},{"de":"Wie lange ist eure geplante Aufenthaltsdauer?","en":"How long is your planned length of stay?","ru":"Какова ваша планируемая продолжительность пребывания?","vi":"Thời gian lưu trú dự định của bạn là bao lâu?","fa":"مدت اقامت برنامه ریزی شده شما چقدر است؟"},{"de":"Bei längerer Aufenthaltsdauer gibt es einen Rabatt.","en":"For a longer length of stay there is a discount.","ru":"При более длительном пребывании есть скидка.","vi":"Có giảm giá nếu ở lâu hơn.","fa":"برای اقامت طولانی مدت تخفیف دارد."}]},{"word":"auffallen","en":"to stand out, be noticeable","ru":"бросаться в глаза, выделяться","vi":"nổi bật","fa":"برجسته شدن","examples":[{"de":"Ihr rotes Kleid fällt sofort auf.","en":"Her red dress stands out immediately.","ru":"Её красное платье сразу бросается в глаза.","vi":"Chiếc váy đỏ của cô gây chú ý ngay lập tức.","fa":"لباس قرمز او بلافاصله به چشم می خورد."},{"de":"Es fiel mir auf, dass er heute sehr müde aussah.","en":"I noticed that he looked very tired today.","ru":"Я заметил, что сегодня он выглядел очень уставшим.","vi":"Tôi nhận thấy hôm nay anh ấy trông rất mệt mỏi.","fa":"من متوجه شدم که او امروز بسیار خسته به نظر می رسد."}]},{"word":"auffordern","en":"to ask/tell someone to do something","ru":"призывать, требовать (сделать что-то)","vi":"nhắc nhở","fa":"سریع","examples":[{"de":"Der Lehrer forderte die Schüler auf, ruhig zu sein.","en":"The teacher told the students to be quiet.","ru":"Учитель призвал учеников вести себя тихо.","vi":"Giáo viên yêu cầu học sinh im lặng.","fa":"معلم از دانش آموزان خواست ساکت باشند."},{"de":"Die Polizei forderte ihn auf, seinen Ausweis zu zeigen.","en":"The police asked him to show his ID.","ru":"Полиция потребовала, чтобы он показал удостоверение личности.","vi":"Cảnh sát yêu cầu anh ta xuất trình giấy tờ tùy thân.","fa":"پلیس از او خواست شناسنامه خود را نشان دهد."}]},{"word":"die Aufforderung","en":"request, demand, prompt","ru":"требование, призыв, побуждение","vi":"yêu cầu","fa":"درخواست","examples":[{"de":"Wir warten noch auf die Aufforderung zur Zahlung.","en":"We are still waiting for the request for payment.","ru":"Мы всё ещё ждём требования об оплате.","vi":"Chúng tôi vẫn đang chờ yêu cầu thanh toán.","fa":"ما همچنان منتظر درخواست پرداخت هستیم."},{"de":"Trotz mehrmaliger Aufforderung kam er nicht.","en":"Despite repeated requests, he did not come.","ru":"Несмотря на неоднократные призывы, он не пришёл.","vi":"Mặc dù nhiều lần yêu cầu nhưng anh ấy vẫn không đến.","fa":"با وجود درخواست های مکرر، او نیامد."},{"de":"Die Aufforderung des Lehrers war sehr deutlich.","en":"The teacher's instruction was very clear.","ru":"Указание учителя было очень чётким.","vi":"Yêu cầu của giáo viên rất rõ ràng.","fa":"درخواست استاد خیلی واضح بود."}]},{"word":"die Aufforstung","en":"reforestation, afforestation","ru":"лесовосстановление, посадка леса","vi":"việc trồng lại rừng","fa":"احیای جنگل","examples":[{"de":"Die Aufforstung soll dem Klima helfen.","en":"Reforestation is meant to help the climate.","ru":"Лесовосстановление должно помочь климату.","vi":"Việc trồng lại rừng nhằm mục đích giúp cải thiện khí hậu.","fa":"احیای جنگل برای کمک به آب و هوا در نظر گرفته شده است."},{"de":"Bei der Aufforstung werden Millionen Bäume gepflanzt.","en":"Millions of trees are planted during reforestation.","ru":"При лесовосстановлении высаживают миллионы деревьев.","vi":"Hàng triệu cây được trồng trong quá trình trồng lại rừng.","fa":"میلیون ها درخت در طول احیای جنگل کاشته می شوند."},{"de":"Freiwillige beteiligen sich an der Aufforstung des Waldes.","en":"Volunteers take part in the reforestation of the woods.","ru":"Волонтёры участвуют в лесовосстановлении.","vi":"Các tình nguyện viên tham gia trồng rừng.","fa":"داوطلبان در احیای جنگل شرکت می کنند."}]},{"word":"aufführen","en":"to perform (a play)","ru":"исполнять, ставить (спектакль)","vi":"thực hiện","fa":"انجام دهد","examples":[{"de":"Das Theater führt heute Abend ein neues Stück auf.","en":"The theater is performing a new play tonight.","ru":"Сегодня вечером театр ставит новую пьесу.","vi":"Nhà hát sẽ biểu diễn một vở kịch mới tối nay.","fa":"این تئاتر امشب نمایش جدیدی را اجرا می کند."},{"de":"Die Schüler führen ein Weihnachtsstück auf.","en":"The students are performing a Christmas play.","ru":"Ученики ставят рождественскую пьесу.","vi":"Học sinh biểu diễn vở kịch Giáng sinh.","fa":"دانش آموزان یک نمایش کریسمس اجرا می کنند."}]},{"word":"die Aufführung","en":"performance (show)","ru":"постановка; спектакль","vi":"hiệu suất","fa":"عملکرد","examples":[{"de":"Die Aufführung des Stücks war ein großer Erfolg.","en":"The performance of the play was a great success.","ru":"Постановка пьесы имела большой успех.","vi":"Buổi biểu diễn của tác phẩm đã thành công tốt đẹp.","fa":"اجرای این قطعه موفقیت بزرگی بود."},{"de":"Nach der Aufführung gab es viel Applaus.","en":"There was a lot of applause after the performance.","ru":"После спектакля было много аплодисментов.","vi":"Có rất nhiều tiếng vỗ tay sau màn trình diễn.","fa":"پس از اجرا تشویق های زیادی به راه افتاد."}]},{"word":"die Aufgabe","en":"task, exercise","ru":"задача, задание","vi":"nhiệm vụ","fa":"وظیفه","examples":[{"de":"Die Lehrerin gibt den Schülern eine schwierige Aufgabe.","en":"The teacher gives the students a difficult task.","ru":"Учительница даёт ученикам сложное задание.","vi":"Giáo viên giao cho học sinh một bài tập khó.","fa":"معلم کار دشواری به دانش آموزان می دهد."},{"de":"Ich habe meine Hausaufgaben noch nicht gemacht.","en":"I haven't done my homework yet.","ru":"Я ещё не сделал домашнее задание.","vi":"Tôi vẫn chưa làm bài tập về nhà.","fa":"من هنوز تکالیفم را انجام نداده ام."}]},{"word":"aufgeben","en":"to give up; to mail (a parcel)","ru":"сдаваться, отказываться; отправлять (посылку)","vi":"từ bỏ","fa":"تسلیم شدن","examples":[{"de":"Er hat das Rauchen endlich aufgegeben.","en":"He has finally given up smoking.","ru":"Он наконец бросил курить.","vi":"Cuối cùng anh ấy đã bỏ thuốc lá.","fa":"بالاخره سیگار را ترک کرد."},{"de":"Ich muss noch ein Paket auf der Post aufgeben.","en":"I still need to mail a package at the post office.","ru":"Мне ещё нужно отправить посылку на почте.","vi":"Tôi vẫn phải gửi gói hàng ở bưu điện.","fa":"من هنوز باید یک بسته را به اداره پست تحویل دهم."}]},{"word":"aufgeregt","en":"excited, nervous, agitated","ru":"взволнованный, возбуждённый, нервный","vi":"vui mừng","fa":"هیجان زده","examples":[{"de":"Vor der Prüfung war ich sehr aufgeregt.","en":"Before the exam I was very nervous.","ru":"Перед экзаменом я очень волновался.","vi":"Tôi đã rất lo lắng trước kỳ thi.","fa":"قبل از امتحان خیلی عصبی بودم."},{"de":"Die Kinder sind vor Weihnachten ganz aufgeregt.","en":"The children are all excited before Christmas.","ru":"Перед Рождеством все дети взволнованы.","vi":"Các em nhỏ rất háo hức trước lễ Giáng sinh.","fa":"بچه ها قبل از کریسمس بسیار هیجان زده هستند."},{"de":"Sie sprach mit aufgeregter Stimme.","en":"She spoke with an agitated voice.","ru":"Она говорила взволнованным голосом.","vi":"Cô nói với giọng phấn khích.","fa":"با صدایی هیجان زده صحبت کرد."}]},{"word":"der Aufguss","en":"infusion (e.g. of herbs or tea)","ru":"настой (напр. трав или чая), заварка","vi":"truyền dịch","fa":"تزریق","examples":[{"de":"Der Aufguss aus frischer Minze beruhigt den Magen.","en":"The infusion of fresh mint soothes the stomach.","ru":"Настой из свежей мяты успокаивает желудок.","vi":"Truyền bạc hà tươi làm dịu dạ dày.","fa":"دم کرده نعناع تازه معده را آرام می کند."},{"de":"Lass den Aufguss fünf Minuten ziehen.","en":"Let the infusion brew for five minutes.","ru":"Дай настою завариться пять минут.","vi":"Để dịch truyền ngấm trong năm phút.","fa":"اجازه دهید دمنوش به مدت پنج دقیقه دم بکشد."},{"de":"Ein heißer Aufguss tut bei Erkältung gut.","en":"A hot infusion is good when you have a cold.","ru":"Горячий настой хорош при простуде.","vi":"Truyền dịch nóng rất tốt cho cảm lạnh.","fa":"دم کرده گرم برای سرماخوردگی مفید است."}]},{"word":"aufhalten","en":"to hold up, delay; (sich aufhalten) to stay","ru":"задерживать; (sich aufhalten) находиться","vi":"dừng lại","fa":"توقف","examples":[{"de":"Der Stau hat uns eine Stunde aufgehalten.","en":"The traffic jam delayed us for an hour.","ru":"Пробка задержала нас на час.","vi":"Ùn tắc giao thông đã khiến chúng tôi bị trì hoãn trong một giờ.","fa":"ترافیک ما را یک ساعت معطل کرد."},{"de":"Er hält sich zurzeit in Berlin auf.","en":"He is currently staying in Berlin.","ru":"Сейчас он находится в Берлине.","vi":"Anh ấy hiện đang ở Berlin.","fa":"او در حال حاضر در برلین است."}]},{"word":"aufheben","en":"to pick up; to keep, save","ru":"поднимать; хранить","vi":"hủy bỏ","fa":"لغو","examples":[{"de":"Kannst du bitte den Stift vom Boden aufheben?","en":"Can you please pick up the pen from the floor?","ru":"Можешь поднять ручку с пола, пожалуйста?","vi":"Bạn có thể vui lòng nhặt cây bút từ dưới sàn lên được không?","fa":"لطفاً می توانید خودکار را از روی زمین بردارید؟"},{"de":"Ich hebe alte Briefe als Erinnerung auf.","en":"I keep old letters as a memento.","ru":"Я храню старые письма на память.","vi":"Tôi giữ những lá thư cũ làm kỷ niệm.","fa":"نامه های قدیمی را به عنوان خاطره نگه می دارم."}]},{"word":"aufhören","en":"to stop","ru":"прекращать, переставать","vi":"dừng lại","fa":"توقف","examples":[{"de":"Der Regen hat endlich aufgehört.","en":"The rain has finally stopped.","ru":"Дождь наконец прекратился.","vi":"Cơn mưa cuối cùng cũng đã tạnh.","fa":"بالاخره باران قطع شد."},{"de":"Hör auf zu schreien!","en":"Stop screaming!","ru":"Перестань кричать!","vi":"Đừng la hét nữa!","fa":"دست از جیغ زدن بردارید!"}]},{"word":"aufkommen","en":"to arise, come up; to cover (costs)","ru":"возникать, подниматься; покрывать (расходы)","vi":"phát sinh","fa":"بوجود می آیند","examples":[{"de":"Plötzlich kam ein starker Wind auf.","en":"Suddenly a strong wind came up.","ru":"Внезапно поднялся сильный ветер.","vi":"Đột nhiên một cơn gió mạnh nổi lên.","fa":"ناگهان باد شدیدی آمد."},{"de":"Es kamen Zweifel auf, ob der Plan funktioniert.","en":"Doubts arose about whether the plan would work.","ru":"Возникли сомнения, сработает ли план.","vi":"Những nghi ngờ nảy sinh về việc liệu kế hoạch có thành công hay không.","fa":"در مورد اینکه آیا این طرح عملی خواهد شد یا خیر، تردیدهایی به وجود آمد."},{"de":"Wer kommt für den Schaden auf?","en":"Who is going to cover the damage?","ru":"Кто покроет ущерб?","vi":"Ai sẽ trả tiền cho thiệt hại?","fa":"چه کسی جبران خسارت می کند؟"}]},{"word":"das Aufladegerät","en":"a charger (for a phone or device)","ru":"зарядное устройство (для телефона или прибора)","vi":"bộ sạc","fa":"شارژر","examples":[{"de":"Das Aufladegerät für das Handy darf ich nicht vergessen.","en":"I mustn't forget the charger for my phone.","ru":"Мне нельзя забыть зарядное устройство для телефона.","vi":"Tôi không thể quên bộ sạc cho điện thoại di động của mình.","fa":"من نمی توانم شارژر تلفن همراهم را فراموش کنم."},{"de":"Mein Akku ist leer und ich habe das Aufladegerät vergessen.","en":"My battery is empty and I have forgotten the charger.","ru":"Батарея разряжена, а зарядное устройство я забыл.","vi":"Máy của tôi hết pin và tôi quên sạc.","fa":"باتری من تمام شده و شارژر را فراموش کرده ام."},{"de":"Kannst du mir kurz dein Aufladegerät leihen?","en":"Can you lend me your charger for a moment?","ru":"Можешь одолжить мне на минутку своё зарядное устройство?","vi":"Bạn có thể cho tôi mượn bộ sạc của bạn một lát được không?","fa":"میشه یه لحظه شارژرتو بهم قرض بدی؟"}]},{"word":"aufladen","en":"to charge (a battery); to load","ru":"заряжать; загружать","vi":"tính phí","fa":"شارژ","examples":[{"de":"Ich muss mein Handy noch aufladen.","en":"I still need to charge my phone.","ru":"Мне ещё нужно зарядить телефон.","vi":"Tôi vẫn cần sạc điện thoại của mình.","fa":"من هنوز باید گوشیم را شارژ کنم."},{"de":"Wir laden die Kisten auf den Lastwagen auf.","en":"We load the boxes onto the truck.","ru":"Мы грузим ящики на грузовик.","vi":"Chúng tôi chất các hộp lên xe tải.","fa":"جعبه ها را روی کامیون بار می کنیم."}]},{"word":"auflösen","en":"to dissolve, resolve; to disband","ru":"растворять; расформировывать","vi":"hòa tan","fa":"حل کردن","examples":[{"de":"Der Zucker löst sich schnell im warmen Wasser auf.","en":"The sugar dissolves quickly in warm water.","ru":"Сахар быстро растворяется в тёплой воде.","vi":"Đường tan nhanh trong nước ấm.","fa":"شکر به سرعت در آب گرم حل می شود."},{"de":"Die Firma wurde nach der Krise aufgelöst.","en":"The company was dissolved after the crisis.","ru":"После кризиса компания была расформирована.","vi":"Công ty đã bị giải thể sau cuộc khủng hoảng.","fa":"این شرکت پس از بحران منحل شد."}]},{"word":"aufmachen","en":"to open","ru":"открывать","vi":"mở ra","fa":"باز کردن","examples":[{"de":"Kannst du bitte das Fenster aufmachen?","en":"Can you please open the window?","ru":"Можешь, пожалуйста, открыть окно?","vi":"Bạn có thể vui lòng mở cửa sổ được không?","fa":"میشه لطفا پنجره رو باز کن"},{"de":"Der Laden macht erst um neun Uhr auf.","en":"The shop only opens at nine o'clock.","ru":"Магазин открывается только в девять.","vi":"Cửa hàng không mở cửa cho đến chín giờ.","fa":"مغازه تا ساعت نه باز نمی شود."},{"de":"Ich habe die Tür für die Gäste aufgemacht.","en":"I opened the door for the guests.","ru":"Я открыл дверь гостям.","vi":"Tôi mở cửa cho khách.","fa":"در را برای مهمانان باز کردم."}]},{"word":"aufmerksam","en":"attentive","ru":"внимательный","vi":"chú ý","fa":"توجه","examples":[{"de":"Die Schüler hören dem Lehrer aufmerksam zu.","en":"The students listen attentively to the teacher.","ru":"Ученики внимательно слушают учителя.","vi":"Học sinh chăm chú lắng nghe giáo viên giảng.","fa":"دانش آموزان با دقت به صحبت های معلم گوش می دهند."},{"de":"Er ist ein aufmerksamer Zuhörer.","en":"He is an attentive listener.","ru":"Он внимательный слушатель.","vi":"Anh ấy là một người biết lắng nghe.","fa":"او شنونده ای با دقت است."}]},{"word":"die Aufnahme","en":"recording, admission, photograph","ru":"запись, зачисление, снимок, приём","vi":"bản ghi âm","fa":"ضبط","examples":[{"de":"Die Aufnahme des Konzerts klingt sehr gut.","en":"The recording of the concert sounds very good.","ru":"Запись концерта звучит очень хорошо.","vi":"Bản thu âm của buổi hòa nhạc nghe rất hay.","fa":"صدای ضبط کنسرت خیلی خوبه"},{"de":"Sie hat die Aufnahme an der Universität geschafft.","en":"She managed to gain admission to the university.","ru":"Ей удалось поступить в университет.","vi":"Cô quản lý để vào được trường đại học.","fa":"او موفق شد وارد دانشگاه شود."},{"de":"Diese Aufnahme zeigt meine Familie im Urlaub.","en":"This photograph shows my family on holiday.","ru":"Этот снимок показывает мою семью на отдыхе.","vi":"Bức ảnh này chụp gia đình tôi đang đi nghỉ.","fa":"این عکس خانواده من را در تعطیلات نشان می دهد."}]},{"word":"aufnehmen","en":"to record; to admit","ru":"записывать; принимать","vi":"ghi lại","fa":"رکورد","examples":[{"de":"Wir nehmen das Konzert auf Video auf.","en":"We record the concert on video.","ru":"Мы записываем концерт на видео.","vi":"Chúng tôi đang ghi lại buổi hòa nhạc trên video.","fa":"در حال ضبط کنسرت به صورت ویدئویی هستیم."},{"de":"Die Universität nimmt jedes Jahr neue Studenten auf.","en":"The university admits new students every year.","ru":"Университет ежегодно принимает новых студентов.","vi":"Trường đại học tiếp nhận sinh viên mới hàng năm.","fa":"این دانشگاه هر ساله دانشجوی جدید می پذیرد."}]},{"word":"aufpassen","en":"to pay attention, watch out; to look after","ru":"быть внимательным; присматривать","vi":"hãy cẩn thận","fa":"مراقب باشید","examples":[{"de":"Pass auf, das Glas ist heiß!","en":"Be careful, the glass is hot!","ru":"Осторожно, стакан горячий!","vi":"Hãy cẩn thận, kính rất nóng!","fa":"مراقب باشید، لیوان داغ است!"},{"de":"Kannst du kurz auf mein Kind aufpassen?","en":"Can you watch my child for a moment?","ru":"Можешь присмотреть за моим ребёнком?","vi":"Bạn có thể trông con tôi một lát được không?","fa":"آیا می توانید یک لحظه مراقب فرزند من باشید؟"}]},{"word":"aufräumen","en":"to tidy up","ru":"убирать, наводить порядок","vi":"dọn dẹp","fa":"پاک کردن","examples":[{"de":"Ich muss noch mein Zimmer aufräumen.","en":"I still need to tidy up my room.","ru":"Мне ещё нужно убрать свою комнату.","vi":"Tôi còn phải dọn phòng nữa.","fa":"هنوز باید اتاقم را تمیز کنم."},{"de":"Die Kinder räumen nach dem Spielen ihr Spielzeug auf.","en":"The children tidy up their toys after playing.","ru":"Дети убирают игрушки после игры.","vi":"Trẻ thu dọn đồ chơi sau khi chơi.","fa":"بچه ها بعد از بازی اسباب بازی های خود را مرتب می کنند."}]},{"word":"aufrecht","en":"upright, erect","ru":"прямой, выпрямленный (об осанке)","vi":"ngay thẳng","fa":"عمودی","examples":[{"de":"Sitze aufrecht und atme ruhig.","en":"Sit upright and breathe calmly.","ru":"Сиди прямо и дыши спокойно.","vi":"Ngồi thẳng và thở bình tĩnh.","fa":"صاف بنشینید و آرام نفس بکشید."},{"de":"Eine aufrechte Haltung ist gut für den Rücken.","en":"An upright posture is good for the back.","ru":"Прямая осанка полезна для спины.","vi":"Tư thế đứng thẳng rất tốt cho lưng của bạn.","fa":"حالت ایستاده برای کمر شما خوب است."},{"de":"Halte den Rücken aufrecht, während du die Arme hebst.","en":"Keep your back upright while you raise your arms.","ru":"Держи спину прямой, поднимая руки.","vi":"Giữ lưng thẳng khi bạn giơ tay lên.","fa":"در حالی که بازوهای خود را بالا می آورید، پشت خود را صاف نگه دارید."}]},{"word":"aufregen","en":"to upset; (sich aufregen) to get worked up","ru":"волновать; (sich aufregen) волноваться, нервничать","vi":"khó chịu","fa":"ناراحت","examples":[{"de":"Reg dich nicht so auf, alles wird gut.","en":"Don't get so upset, everything will be fine.","ru":"Не волнуйся так, всё будет хорошо.","vi":"Đừng buồn quá, mọi chuyện sẽ ổn thôi.","fa":"انقدر ناراحت نباش همه چی درست میشه"},{"de":"Die schlechte Nachricht hat sie sehr aufgeregt.","en":"The bad news upset her a lot.","ru":"Плохая новость сильно её взволновала.","vi":"Tin dữ khiến cô rất buồn.","fa":"خبر بد او را بسیار ناراحت کرد."}]},{"word":"die Aufregung","en":"excitement; agitation","ru":"волнение","vi":"sự phấn khích","fa":"هیجان","examples":[{"de":"Vor der Reise herrschte große Aufregung.","en":"There was great excitement before the trip.","ru":"Перед поездкой царило большое волнение.","vi":"Có sự phấn khích lớn trước chuyến đi.","fa":"قبل از سفر هیجان زیادی وجود داشت."},{"de":"Nach der ganzen Aufregung musste sie sich erst einmal hinsetzen.","en":"After all the excitement she had to sit down first.","ru":"После всего этого волнения ей сначала пришлось присесть.","vi":"Sau bao phấn khích, cô phải ngồi xuống trước.","fa":"بعد از کلی هیجان، اول باید بنشیند."}]},{"word":"aufschreiben","en":"to write down; to note down","ru":"записывать (на бумаге)","vi":"viết ra","fa":"یادداشت کنید","examples":[{"de":"Ich schreibe mir die Adresse schnell auf.","en":"I'll quickly write the address down for myself.","ru":"Я быстро запишу себе адрес.","vi":"Tôi nhanh chóng ghi lại địa chỉ.","fa":"سریع آدرس را می نویسم."},{"de":"Hast du die Telefonnummer aufgeschrieben?","en":"Did you write down the telephone number?","ru":"Ты записал номер телефона?","vi":"Bạn có ghi số điện thoại không?","fa":"شماره تلفن را یادداشت کردی؟"},{"de":"Bitte schreib alle Ideen auf, bevor du sie vergisst.","en":"Please note down all ideas before you forget them.","ru":"Пожалуйста, запиши все идеи, пока не забыл.","vi":"Hãy viết ra tất cả các ý tưởng trước khi bạn quên chúng.","fa":"لطفاً قبل از اینکه همه ایده ها را فراموش کنید یادداشت کنید."}]},{"word":"der Aufstand","en":"uprising, revolt","ru":"восстание, мятеж","vi":"cuộc nổi dậy","fa":"the uprising","examples":[{"de":"Der Aufstand gegen den König wurde blutig niedergeschlagen.","en":"The uprising against the king was bloodily put down.","ru":"Восстание против короля было жестоко подавлено.","vi":"Cuộc nổi dậy chống lại nhà vua bị đàn áp đẫm máu.","fa":"قیام علیه شاه به صورت خونین سرکوب شد."},{"de":"Im Jahr 1953 kam es zu einem großen Aufstand.","en":"In 1953 a large uprising broke out.","ru":"В 1953 году вспыхнуло большое восстание.","vi":"Năm 1953 xảy ra một cuộc nổi dậy lớn.","fa":"در سال 1953 یک قیام بزرگ رخ داد."},{"de":"Der Aufstand begann mit friedlichen Protesten.","en":"The uprising began with peaceful protests.","ru":"Восстание началось с мирных протестов.","vi":"Cuộc nổi dậy bắt đầu bằng những cuộc biểu tình ôn hòa.","fa":"این قیام با تظاهرات مسالمت آمیز آغاز شد."}]},{"word":"aufstehen","en":"to get up, stand up","ru":"вставать","vi":"thức dậy","fa":"بلند شو","examples":[{"de":"Ich stehe jeden Morgen um sechs Uhr auf.","en":"I get up every morning at six o'clock.","ru":"Я встаю каждое утро в шесть часов.","vi":"Tôi thức dậy lúc sáu giờ mỗi sáng.","fa":"هر روز صبح ساعت شش بیدار می شوم."},{"de":"Er steht vom Stuhl auf und geht zur Tür.","en":"He gets up from the chair and goes to the door.","ru":"Он встаёт со стула и идёт к двери.","vi":"Anh đứng dậy khỏi ghế và đi ra cửa.","fa":"از روی صندلی بلند می شود و به سمت در می رود."}]},{"word":"aufteilen","en":"to divide up; to share out","ru":"делить, распределять","vi":"chia","fa":"تقسیم کنید","examples":[{"de":"Wir teilen die Arbeit unter uns auf.","en":"We divide the work up among ourselves.","ru":"Мы распределяем работу между собой.","vi":"Chúng tôi phân chia công việc giữa chúng tôi.","fa":"ما کار را بین خود تقسیم می کنیم."},{"de":"Lass uns den Kuchen in acht Stücke aufteilen.","en":"Let's divide the cake into eight pieces.","ru":"Давай разделим торт на восемь кусков.","vi":"Hãy chia chiếc bánh thành tám phần.","fa":"کیک را به هشت قسمت تقسیم می کنیم."},{"de":"Die Lehrerin teilte die Klasse in zwei Gruppen auf.","en":"The teacher divided the class into two groups.","ru":"Учитель разделил класс на две группы.","vi":"Giáo viên chia lớp thành hai nhóm.","fa":"معلم کلاس را به دو گروه تقسیم کرد."}]},{"word":"der Auftrag","en":"order, assignment","ru":"заказ, поручение","vi":"thứ tự","fa":"سفارش","examples":[{"de":"Die Firma hat einen großen Auftrag bekommen.","en":"The company received a large order.","ru":"Компания получила крупный заказ.","vi":"Công ty đã nhận được một đơn đặt hàng lớn.","fa":"این شرکت سفارش بزرگی دریافت کرد."},{"de":"Ich erledige diesen Auftrag im Namen meines Chefs.","en":"I'm carrying out this task on behalf of my boss.","ru":"Я выполняю это поручение от имени своего начальника.","vi":"Tôi đang hoàn thành nhiệm vụ này thay mặt cho ông chủ của tôi.","fa":"من این وظیفه را از طرف رئیسم انجام می دهم."}]},{"word":"auftreten","en":"to appear, perform; to occur","ru":"выступать; возникать","vi":"xảy ra","fa":"رخ دهد","examples":[{"de":"Die Band tritt heute Abend live auf.","en":"The band performs live tonight.","ru":"Сегодня вечером группа выступает вживую.","vi":"Ban nhạc sẽ biểu diễn trực tiếp tối nay.","fa":"این گروه امشب اجرای زنده دارد."},{"de":"Bei der Arbeit können unerwartete Probleme auftreten.","en":"Unexpected problems can occur at work.","ru":"На работе могут возникнуть неожиданные проблемы.","vi":"Những vấn đề không mong muốn có thể phát sinh trong công việc.","fa":"ممکن است مشکلات غیرمنتظره ای در محل کار ایجاد شود."}]},{"word":"aufwachen","en":"to wake up","ru":"просыпаться","vi":"thức dậy","fa":"بیدار شو","examples":[{"de":"Ich wache normalerweise um sieben Uhr auf.","en":"I usually wake up at seven o'clock.","ru":"Я обычно просыпаюсь в семь часов.","vi":"Tôi thường thức dậy lúc bảy giờ.","fa":"من معمولا ساعت هفت از خواب بیدار می شوم."},{"de":"Das Baby ist mitten in der Nacht aufgewacht.","en":"The baby woke up in the middle of the night.","ru":"Ребёнок проснулся посреди ночи.","vi":"Đứa bé thức dậy vào giữa đêm.","fa":"بچه نیمه شب از خواب بیدار شد."}]},{"word":"aufwärts","en":"upwards","ru":"вверх","vi":"trở lên","fa":"به سمت بالا","examples":[{"de":"Der Weg führt steil aufwärts.","en":"The path leads steeply upwards.","ru":"Тропа круто ведёт вверх.","vi":"Con đường dẫn dốc lên trên.","fa":"مسیر با شیب تند به سمت بالا منتهی می شود."},{"de":"Nach der Krise geht es mit der Wirtschaft wieder aufwärts.","en":"After the crisis, the economy is improving again.","ru":"После кризиса экономика снова идёт на подъём.","vi":"Sau cuộc khủng hoảng, nền kinh tế đang được cải thiện trở lại.","fa":"پس از بحران، اقتصاد دوباره در حال بهبود است."}]},{"word":"der Aufzug","en":"elevator, lift","ru":"лифт","vi":"thang máy","fa":"آسانسور","examples":[{"de":"Der Aufzug ist leider defekt, wir müssen die Treppe nehmen.","en":"The elevator is unfortunately broken, we have to take the stairs.","ru":"Лифт, к сожалению, не работает, нам придётся идти по лестнице.","vi":"Thật không may thang máy bị hỏng, chúng tôi phải đi cầu thang bộ.","fa":"متاسفانه آسانسور خراب است، باید از پله ها برویم."},{"de":"Wir fahren mit dem Aufzug in den fünften Stock.","en":"We take the elevator to the fifth floor.","ru":"Мы поднимаемся на лифте на пятый этаж.","vi":"Chúng tôi đi thang máy lên tầng năm.","fa":"با آسانسور به طبقه پنجم می رویم."}]},{"word":"das Auge","en":"eye","ru":"глаз","vi":"con mắt","fa":"چشم","examples":[{"de":"Sie hat wunderschöne blaue Augen.","en":"She has beautiful blue eyes.","ru":"У неё красивые голубые глаза.","vi":"Cô ấy có đôi mắt xanh tuyệt đẹp.","fa":"او چشمان آبی زیبایی دارد."},{"de":"Ich reibe mir müde die Augen.","en":"I rub my tired eyes.","ru":"Я тру уставшие глаза.","vi":"Tôi dụi mắt mệt mỏi.","fa":"چشمانم را خسته می مالیم."}]},{"word":"der Augenblick","en":"moment","ru":"мгновение, момент","vi":"khoảnh khắc","fa":"لحظه","examples":[{"de":"Einen Augenblick, bitte, ich bin gleich da.","en":"One moment please, I'll be right there.","ru":"Одну минутку, пожалуйста, я сейчас подойду.","vi":"Xin vui lòng chờ một lát, tôi sẽ đến đó ngay.","fa":"فقط یک لحظه، لطفا، من یک لحظه دیگر آنجا خواهم بود."},{"de":"In diesem Augenblick klingelte das Telefon.","en":"At that moment the phone rang.","ru":"В этот момент зазвонил телефон.","vi":"Đúng lúc đó điện thoại reo.","fa":"در همان لحظه تلفن زنگ خورد."}]},{"word":"aus","en":"out of, from; off","ru":"из; выключено","vi":"ra ngoài","fa":"بیرون","examples":[{"de":"Er kommt aus Spanien.","en":"He comes from Spain.","ru":"Он родом из Испании.","vi":"Anh ấy đến từ Tây Ban Nha.","fa":"او از اسپانیا می آید."},{"de":"Mach bitte das Licht aus.","en":"Please turn off the light.","ru":"Пожалуйста, выключи свет.","vi":"Làm ơn tắt đèn đi.","fa":"لطفا چراغ ها را خاموش کنید"}]},{"word":"aus einer Mücke einen Elefanten machen","en":"to make a mountain out of a molehill","ru":"делать из мухи слона","vi":"để tạo ra một ngọn núi từ một con chuột chũi","fa":"ساختن کوه از تپه خال","examples":[{"de":"Reg dich nicht auf, du machst aus einer Mücke einen Elefanten.","en":"Don't get upset, you're making a mountain out of a molehill.","ru":"Не переживай, ты делаешь из мухи слона.","vi":"Đừng buồn, bạn đang biến con muỗi thành con voi đấy.","fa":"ناراحت نشو، پشه را به فیل تبدیل می کنی."}]},{"word":"das Ausatmen","en":"exhaling, breathing out","ru":"выдох, выдыхание","vi":"sự thở ra","fa":"بازدم","examples":[{"de":"Beim Ausatmen senkst du den Oberkörper zum Boden.","en":"As you breathe out, you lower your upper body to the floor.","ru":"На выдохе ты опускаешь корпус к полу.","vi":"Khi bạn thở ra, hạ thấp phần thân trên của bạn xuống sàn.","fa":"در حین بازدم، بالاتنه خود را روی زمین پایین بیاورید."},{"de":"Das langsame Ausatmen hilft dir, dich zu entspannen.","en":"Slow exhaling helps you to relax.","ru":"Медленный выдох помогает расслабиться.","vi":"Thở ra từ từ giúp bạn thư giãn.","fa":"بازدم به آرامی به شما کمک می کند تا آرام شوید."},{"de":"Lass beim Ausatmen die Schultern sinken.","en":"Let your shoulders drop as you breathe out.","ru":"На выдохе опусти плечи.","vi":"Khi bạn thở ra, hãy để vai bạn thả lỏng.","fa":"همانطور که نفس خود را بیرون می دهید، اجازه دهید شانه هایتان بیفتد."}]},{"word":"die Ausatmung","en":"exhalation","ru":"выдох, выдыхание (как процесс)","vi":"sự thở ra","fa":"بازدم","examples":[{"de":"Bei der Ausatmung senkst du den Oberkörper nach vorne.","en":"On the exhalation you lower your upper body forward.","ru":"На выдохе ты опускаешь корпус вперёд.","vi":"Khi bạn thở ra, hạ thấp phần thân trên về phía trước.","fa":"هنگام بازدم، بالاتنه خود را به سمت جلو پایین بیاورید."},{"de":"Eine lange Ausatmung hilft beim Loslassen.","en":"A long exhalation helps with letting go.","ru":"Долгий выдох помогает отпустить.","vi":"Thở ra dài giúp bạn buông bỏ.","fa":"بازدم طولانی به شما کمک می کند که رها شوید."},{"de":"Mach die Ausatmung doppelt so lang wie die Einatmung.","en":"Make the exhalation twice as long as the inhalation.","ru":"Делай выдох вдвое длиннее вдоха.","vi":"Thời gian thở ra dài gấp đôi thời gian hít vào.","fa":"بازدم را دو برابر زمان دم طولانی کنید."}]},{"word":"ausbilden","en":"to train; to educate","ru":"обучать, готовить (специалистов); давать образование","vi":"xe lửa","fa":"قطار","examples":[{"de":"Der Betrieb bildet jedes Jahr drei Lehrlinge aus.","en":"The company trains three apprentices every year.","ru":"Компания каждый год обучает трёх учеников.","vi":"Công ty đào tạo 3 học viên mỗi năm.","fa":"این شرکت هر سال سه کارآموز تربیت می کند."},{"de":"Sie lässt sich zur Krankenschwester ausbilden.","en":"She is training to be a nurse.","ru":"Она учится на медсестру.","vi":"Cô ấy đang được đào tạo để trở thành y tá.","fa":"او در حال آموزش پرستاری است."},{"de":"Wir bilden unsere Mitarbeiter regelmäßig weiter aus.","en":"We continually train our staff further.","ru":"Мы постоянно повышаем квалификацию наших сотрудников.","vi":"Chúng tôi thường xuyên đào tạo nhân viên của mình.","fa":"ما به طور منظم کارکنان خود را آموزش می دهیم."}]},{"word":"die Ausbildung","en":"vocational training, education","ru":"профессиональное обучение","vi":"việc đào tạo","fa":"آموزش","examples":[{"de":"Sie macht eine Ausbildung zur Krankenschwester.","en":"She is doing vocational training to become a nurse.","ru":"Она проходит обучение на медсестру.","vi":"Cô ấy đang được đào tạo để trở thành y tá.","fa":"او در حال آموزش پرستاری است."},{"de":"Nach der Schule beginnt er eine Ausbildung als Elektriker.","en":"After school he starts an apprenticeship as an electrician.","ru":"После школы он начинает обучение на электрика.","vi":"Sau giờ học, anh bắt đầu học nghề thợ điện.","fa":"پس از مدرسه، آموزش به عنوان برق را آغاز می کند."}]},{"word":"ausdrucken","en":"to print out","ru":"распечатывать","vi":"in ra","fa":"چاپ کنید","examples":[{"de":"Kannst du mir das Dokument ausdrucken?","en":"Can you print out the document for me?","ru":"Можешь распечатать мне этот документ?","vi":"Bạn có thể in tài liệu ra cho tôi được không?","fa":"آیا می توانید سند را برای من پرینت بگیرید؟"},{"de":"Ich drucke die Fahrkarte zu Hause aus.","en":"I print the ticket out at home.","ru":"Я распечатываю билет дома.","vi":"Tôi in vé ở nhà.","fa":"من بلیط را در خانه پرینت می کنم."}]},{"word":"ausdrücken","en":"to express","ru":"выражать","vi":"thể hiện","fa":"بیان کنید","examples":[{"de":"Er konnte seine Gefühle nur schwer ausdrücken.","en":"He found it hard to express his feelings.","ru":"Ему было трудно выражать свои чувства.","vi":"Anh ấy cảm thấy khó khăn khi bày tỏ cảm xúc của mình.","fa":"بیان احساساتش برایش سخت بود."},{"de":"Wie drückt man das auf Deutsch aus?","en":"How do you express that in German?","ru":"Как это выразить по-немецки?","vi":"Làm thế nào để bạn diễn đạt điều đó bằng tiếng Đức?","fa":"چگونه آن را به آلمانی بیان می کنید؟"}]},{"word":"auseinander","en":"apart","ru":"врозь, порознь, друг от друга","vi":"xa nhau","fa":"جدا","examples":[{"de":"Die Kinder sitzen weit auseinander.","en":"The children sit far apart.","ru":"Дети сидят далеко друг от друга.","vi":"Bọn trẻ ngồi cách xa nhau.","fa":"بچه ها دور از هم می نشینند."},{"de":"Er hat den Motor auseinandergenommen.","en":"He took the engine apart.","ru":"Он разобрал двигатель.","vi":"Anh tháo động cơ ra.","fa":"موتور را از هم جدا کرد."}]},{"word":"die Auseinandersetzung","en":"dispute, confrontation, engagement with a topic","ru":"спор, столкновение; разбор (изучение темы)","vi":"lập luận","fa":"استدلال","examples":[{"de":"Es kam zu einer heftigen Auseinandersetzung zwischen den Kollegen.","en":"There was a heated dispute between the colleagues.","ru":"Между коллегами произошёл ожесточённый спор.","vi":"Giữa các đồng nghiệp đã xảy ra tranh cãi nảy lửa.","fa":"درگیری شدیدی بین همکاران درگرفت."},{"de":"Die Auseinandersetzung mit dem Thema war sehr lehrreich.","en":"Engaging with the topic was very instructive.","ru":"Разбор этой темы был очень поучительным.","vi":"Việc xử lý chủ đề này rất mang tính hướng dẫn.","fa":"پرداختن به موضوع بسیار آموزنده بود."},{"de":"Nach der Auseinandersetzung versöhnten sich die beiden wieder.","en":"After the confrontation the two reconciled again.","ru":"После столкновения оба снова помирились.","vi":"Sau khi tranh cãi, cả hai đã làm hòa.","fa":"پس از مشاجره، آن دو با هم آشتی کردند."}]},{"word":"die Ausfahrt","en":"exit (highway)","ru":"выезд","vi":"lối ra","fa":"خروجی","examples":[{"de":"Nehmen Sie die nächste Ausfahrt von der Autobahn.","en":"Take the next exit from the highway.","ru":"Съезжайте на следующем выезде с автомагистрали.","vi":"Đi theo lối ra tiếp theo từ đường cao tốc.","fa":"از خروجی بعدی از بزرگراه خارج شوید."},{"de":"Die Ausfahrt zur Innenstadt ist gesperrt.","en":"The exit to the city center is closed.","ru":"Выезд в центр города закрыт.","vi":"Lối ra vào trung tâm thành phố đã bị đóng.","fa":"خروجی مرکز شهر بسته است."}]},{"word":"ausfallen","en":"to be cancelled; to fall out (hair)","ru":"отменяться; выпадать","vi":"thất bại","fa":"شکست بخورد","examples":[{"de":"Der Unterricht fällt heute wegen Krankheit des Lehrers aus.","en":"Class is cancelled today because the teacher is sick.","ru":"Сегодня урок отменяется из-за болезни учителя.","vi":"Hôm nay lớp học được nghỉ do giáo viên bị bệnh.","fa":"کلاس ها امروز به دلیل بیماری معلم لغو شد."},{"de":"Nach der Krankheit sind ihr die Haare ausgefallen.","en":"After the illness, her hair fell out.","ru":"После болезни у неё выпали волосы.","vi":"Sau cơn bệnh, tóc cô rụng dần.","fa":"بعد از بیماری موهایش ریخت."}]},{"word":"der Ausflug","en":"excursion, trip","ru":"экскурсия, поездка","vi":"chuyến tham quan","fa":"گشت و گذار","examples":[{"de":"Am Wochenende machen wir einen Ausflug in die Berge.","en":"On the weekend we're going on a trip to the mountains.","ru":"На выходных мы отправляемся на экскурсию в горы.","vi":"Vào cuối tuần chúng tôi sẽ đi du lịch lên núi.","fa":"آخر هفته میریم یه سفر به کوه."},{"de":"Die Schulklasse macht einen Ausflug ins Museum.","en":"The school class is going on a trip to the museum.","ru":"Школьный класс отправляется на экскурсию в музей.","vi":"Lớp học đi tham quan bảo tàng.","fa":"کلاس مدرسه به موزه می رود."}]},{"word":"ausführlich","en":"detailed, thorough","ru":"подробный, обстоятельный","vi":"chi tiết","fa":"دقیق","examples":[{"de":"Er erklärte den Plan sehr ausführlich.","en":"He explained the plan in great detail.","ru":"Он очень подробно объяснил план.","vi":"Anh ấy giải thích kế hoạch rất chi tiết.","fa":"او این طرح را با جزئیات کامل توضیح داد."},{"de":"Wir haben das Thema ausführlich besprochen.","en":"We discussed the topic thoroughly.","ru":"Мы обстоятельно обсудили эту тему.","vi":"Chúng tôi đã thảo luận chi tiết về chủ đề này.","fa":"موضوع را به تفصیل مورد بحث قرار دادیم."},{"de":"Die Anleitung ist erfreulich ausführlich.","en":"The manual is pleasingly detailed.","ru":"Инструкция приятно подробная.","vi":"Các hướng dẫn rất chi tiết.","fa":"دستورالعمل ها به طرز دلپذیری مفصل است."}]},{"word":"ausfüllen","en":"to fill out (a form)","ru":"заполнять (анкету)","vi":"điền vào","fa":"پر کن","examples":[{"de":"Bitte füllen Sie das Formular vollständig aus.","en":"Please fill out the form completely.","ru":"Пожалуйста, заполните бланк полностью.","vi":"Vui lòng điền đầy đủ vào mẫu đơn.","fa":"لطفا فرم را به طور کامل پر کنید."},{"de":"Ich habe den Antrag schon ausgefüllt.","en":"I have already filled out the application.","ru":"Я уже заполнил заявление.","vi":"Tôi đã điền đơn rồi.","fa":"من قبلاً درخواست را پر کرده ام."}]},{"word":"die Ausgabe","en":"expense; edition, issue","ru":"расход; выпуск, издание","vi":"đầu ra","fa":"خروجی","examples":[{"de":"Unsere monatlichen Ausgaben sind gestiegen.","en":"Our monthly expenses have increased.","ru":"Наши ежемесячные расходы увеличились.","vi":"Chi phí hàng tháng của chúng tôi đã tăng lên.","fa":"هزینه های ماهانه ما افزایش یافته است."},{"de":"Diese Zeitschrift erscheint in einer neuen Ausgabe.","en":"This magazine is coming out in a new edition.","ru":"Этот журнал выходит новым выпуском.","vi":"Tạp chí này xuất hiện trong một ấn bản mới.","fa":"این مجله در نسخه جدید منتشر می شود."}]},{"word":"die Ausgaben","en":"expenses, expenditure","ru":"расходы, траты","vi":"các chi phí","fa":"هزینه ها","examples":[{"de":"Am Monatsende notiere ich alle meine Ausgaben.","en":"At the end of the month I note down all my expenses.","ru":"В конце месяца я записываю все свои расходы.","vi":"Vào cuối tháng tôi viết ra tất cả các chi phí của mình.","fa":"آخر ماه تمام هزینه هایم را یادداشت می کنم."},{"de":"Die Ausgaben für Lebensmittel sind gestiegen.","en":"The expenses for food have risen.","ru":"Расходы на продукты выросли.","vi":"Chi tiêu cho thực phẩm đã tăng lên.","fa":"هزینه برای غذا افزایش یافته است."},{"de":"Wir müssen unsere Ausgaben besser kontrollieren.","en":"We have to control our expenses better.","ru":"Нам нужно лучше контролировать свои расходы.","vi":"Chúng ta cần kiểm soát chi tiêu của mình tốt hơn.","fa":"ما باید مخارج خود را بهتر کنترل کنیم."}]},{"word":"die Ausgabenkontrolle","en":"control of expenses, budgeting","ru":"контроль расходов","vi":"kiểm soát chi tiêu","fa":"کنترل مخارج","examples":[{"de":"Eine strenge Ausgabenkontrolle hilft beim Sparen.","en":"Strict control of expenses helps with saving.","ru":"Строгий контроль расходов помогает копить.","vi":"Kiểm soát chi tiêu chặt chẽ giúp bạn tiết kiệm.","fa":"کنترل دقیق هزینه ها به شما کمک می کند پس انداز کنید."},{"de":"Mit einer App behalte ich die Ausgabenkontrolle.","en":"With an app I keep control of my expenses.","ru":"С помощью приложения я контролирую расходы.","vi":"Với một ứng dụng, tôi có thể kiểm soát chi phí của mình.","fa":"با یک برنامه من کنترل هزینه های خود را حفظ می کنم."},{"de":"Ohne Ausgabenkontrolle gibt man schnell zu viel aus.","en":"Without control of expenses you quickly spend too much.","ru":"Без контроля расходов быстро тратишь слишком много.","vi":"Nếu không kiểm soát chi tiêu thì rất dễ chi tiêu quá nhiều.","fa":"بدون کنترل مخارج، خرج کردن بیش از حد آسان است."}]},{"word":"der Ausgang","en":"exit","ru":"выход","vi":"lối ra","fa":"خروجی","examples":[{"de":"Der Ausgang befindet sich am Ende des Flurs.","en":"The exit is at the end of the hallway.","ru":"Выход находится в конце коридора.","vi":"Lối ra nằm ở cuối hành lang.","fa":"خروجی در انتهای راهرو است."},{"de":"Bitte benutzen Sie im Notfall den nächsten Ausgang.","en":"In an emergency, please use the nearest exit.","ru":"В случае чрезвычайной ситуации, пожалуйста, воспользуйтесь ближайшим выходом.","vi":"Trong trường hợp khẩn cấp, vui lòng sử dụng lối thoát hiểm gần nhất.","fa":"در مواقع اضطراری لطفا از نزدیکترین خروجی استفاده کنید."}]},{"word":"ausgeben","en":"to spend (money); to distribute","ru":"тратить (деньги); раздавать","vi":"đầu ra","fa":"خروجی","examples":[{"de":"Er gibt viel Geld für Kleidung aus.","en":"He spends a lot of money on clothes.","ru":"Он тратит много денег на одежду.","vi":"Anh ấy chi rất nhiều tiền vào quần áo.","fa":"پول زیادی برای لباس خرج می کند."},{"de":"Die Lehrerin gibt die Prüfungsblätter aus.","en":"The teacher hands out the exam sheets.","ru":"Учительница раздаёт экзаменационные листы.","vi":"Giáo viên phát đề thi.","fa":"معلم برگه های امتحان را می دهد."}]},{"word":"ausgehen","en":"to go out; to run out","ru":"выходить (развлекаться); заканчиваться","vi":"đi ra ngoài","fa":"برو بیرون","examples":[{"de":"Am Samstag gehen wir mit Freunden aus.","en":"On Saturday we're going out with friends.","ru":"В субботу мы идём куда-то с друзьями.","vi":"Vào thứ bảy chúng tôi đi chơi với bạn bè.","fa":"شنبه با دوستان میریم بیرون."},{"de":"Uns ist das Benzin ausgegangen.","en":"We ran out of gas.","ru":"У нас закончился бензин.","vi":"Chúng tôi hết xăng.","fa":"بنزینمان تمام شد."}]},{"word":"ausgezeichnet","en":"excellent","ru":"отличный, превосходный","vi":"xuất sắc","fa":"عالی","examples":[{"de":"Das Essen in diesem Restaurant ist ausgezeichnet.","en":"The food in this restaurant is excellent.","ru":"Еда в этом ресторане превосходная.","vi":"Đồ ăn ở nhà hàng này rất tuyệt vời.","fa":"غذاهای این رستوران عالی است."},{"de":"Sie hat die Prüfung mit ausgezeichneten Ergebnissen bestanden.","en":"She passed the exam with excellent results.","ru":"Она сдала экзамен с отличными результатами.","vi":"Cô đã vượt qua kỳ thi với kết quả xuất sắc.","fa":"او امتحان را با نتایج عالی قبول کرد."}]},{"word":"die Ausgrenzung","en":"exclusion","ru":"исключение, отчуждение (из общества)","vi":"sự loại trừ","fa":"محرومیت","examples":[{"de":"Die Ausgrenzung einzelner Menschen ist ein soziales Problem.","en":"The exclusion of individuals is a social problem.","ru":"Исключение отдельных людей — социальная проблема.","vi":"Việc loại trừ các cá nhân là một vấn đề xã hội.","fa":"طرد شدن افراد یک معضل اجتماعی است."},{"de":"Viele leiden unter der Ausgrenzung in der Schule.","en":"Many suffer from exclusion at school.","ru":"Многие страдают от отчуждения в школе.","vi":"Nhiều người bị loại trừ ở trường.","fa":"بسیاری از محرومیت در مدرسه رنج می برند."},{"de":"Wir müssen gegen jede Form von Ausgrenzung kämpfen.","en":"We must fight against every form of exclusion.","ru":"Мы должны бороться с любой формой исключения.","vi":"Chúng ta phải đấu tranh chống lại mọi hình thức loại trừ.","fa":"ما باید با هر نوع محرومیت مبارزه کنیم."}]},{"word":"die Aushilfe","en":"temporary worker, help","ru":"временный работник","vi":"sự giúp đỡ tạm thời","fa":"کمک موقت","examples":[{"de":"Wir suchen eine Aushilfe für das Wochenende.","en":"We're looking for a temporary worker for the weekend.","ru":"Мы ищем временного работника на выходные.","vi":"Chúng tôi đang tìm kiếm một công nhân tạm thời vào cuối tuần.","fa":"به دنبال کارگر موقت برای آخر هفته هستیم."},{"de":"Sie arbeitet als Aushilfe im Supermarkt.","en":"She works as a temp in the supermarket.","ru":"Она подрабатывает в супермаркете.","vi":"Cô làm công nhân tạm thời ở siêu thị.","fa":"او به عنوان کارگر موقت در سوپرمارکت کار می کند."}]},{"word":"die Auskunft","en":"information","ru":"справка, информация","vi":"thông tin","fa":"اطلاعات","examples":[{"de":"Können Sie mir eine Auskunft über die Zugverbindungen geben?","en":"Can you give me information about the train connections?","ru":"Можете дать мне справку о железнодорожном сообщении?","vi":"Bạn có thể cho tôi thông tin về các chuyến tàu kết nối được không?","fa":"آیا می توانید اطلاعاتی در مورد اتصالات قطار به من بدهید؟"},{"de":"Am Schalter erhalten Sie weitere Auskünfte.","en":"You can get further information at the counter.","ru":"У стойки вы можете получить дополнительную информацию.","vi":"Bạn có thể lấy thêm thông tin tại quầy.","fa":"اطلاعات بیشتر را می توانید از پیشخوان دریافت کنید."}]},{"word":"das Ausland","en":"foreign countries, abroad","ru":"заграница, за рубежом","vi":"nước ngoài","fa":"کشور خارجی","examples":[{"de":"Sie hat drei Jahre im Ausland gelebt.","en":"She lived abroad for three years.","ru":"Она три года жила за границей.","vi":"Cô sống ở nước ngoài được ba năm.","fa":"او سه سال در خارج از کشور زندگی کرد."},{"de":"Viele Studenten möchten ein Semester im Ausland studieren.","en":"Many students want to study a semester abroad.","ru":"Многие студенты хотят учиться семестр за границей.","vi":"Nhiều sinh viên muốn đi du học trong một học kỳ.","fa":"بسیاری از دانشجویان می خواهند برای یک ترم در خارج از کشور تحصیل کنند."}]},{"word":"ausländisch","en":"foreign","ru":"иностранный, зарубежный","vi":"nước ngoài","fa":"خارجی","examples":[{"de":"Viele ausländische Studenten studieren an dieser Universität.","en":"Many foreign students study at this university.","ru":"В этом университете учатся многие иностранные студенты.","vi":"Nhiều sinh viên nước ngoài học tại trường đại học này.","fa":"بسیاری از دانشجویان خارجی در این دانشگاه تحصیل می کنند."},{"de":"Die Stadt ist offen für ausländische Mitbürger.","en":"The city is open to foreign fellow citizens.","ru":"Город открыт для иностранных сограждан.","vi":"Thành phố mở cửa cho công dân nước ngoài.","fa":"این شهر برای شهروندان خارجی باز است."},{"de":"Ausländische Fachkräfte sind auf dem Arbeitsmarkt gefragt.","en":"Foreign skilled workers are in demand on the labour market.","ru":"Иностранные специалисты востребованы на рынке труда.","vi":"Thị trường lao động đang có nhu cầu về lao động có tay nghề nước ngoài.","fa":"کارگران ماهر خارجی در بازار کار مورد تقاضا هستند."}]},{"word":"ausmachen","en":"to turn off; to matter","ru":"выключать; иметь значение","vi":"làm ra","fa":"درست کردن","examples":[{"de":"Bitte mach den Fernseher aus.","en":"Please turn off the TV.","ru":"Пожалуйста, выключи телевизор.","vi":"Hãy tắt TV đi.","fa":"لطفا تلویزیون را خاموش کنید."},{"de":"Es macht mir nichts aus, früh aufzustehen.","en":"It doesn't matter to me to get up early.","ru":"Мне не составляет труда рано вставать.","vi":"Tôi không ngại dậy sớm.","fa":"بدم نمیاد زود بیدار بشم"}]},{"word":"die Ausnahme","en":"exception","ru":"исключение","vi":"ngoại lệ","fa":"استثنا","examples":[{"de":"Diese Regel hat keine Ausnahme.","en":"This rule has no exception.","ru":"У этого правила нет исключений.","vi":"Quy tắc này không có ngoại lệ.","fa":"این قاعده استثنا ندارد."},{"de":"Nur in Ausnahmefällen dürfen Handys benutzt werden.","en":"Mobile phones may only be used in exceptional cases.","ru":"Мобильными телефонами можно пользоваться только в исключительных случаях.","vi":"Điện thoại di động chỉ có thể được sử dụng trong những trường hợp đặc biệt.","fa":"تلفن های همراه فقط در موارد استثنایی قابل استفاده هستند."}]},{"word":"ausprobieren","en":"to try out; to test","ru":"пробовать, испытывать","vi":"thử nó đi","fa":"آن را امتحان کنید","examples":[{"de":"Ich möchte das neue Rezept einmal ausprobieren.","en":"I would like to try out the new recipe once.","ru":"Я хотел бы разок попробовать новый рецепт.","vi":"Tôi muốn thử công thức mới.","fa":"من می خواهم دستور پخت جدید را امتحان کنم."},{"de":"Hast du die App schon ausprobiert?","en":"Have you already tried out the app?","ru":"Ты уже попробовал приложение?","vi":"Bạn đã thử ứng dụng này chưa?","fa":"آیا تا به حال برنامه را امتحان کرده اید؟"},{"de":"Probier den Kuchen mal aus, er ist sehr lecker.","en":"Try out the cake, it is very tasty.","ru":"Попробуй пирог, он очень вкусный.","vi":"Hãy thử bánh, nó rất ngon.","fa":"کیک رو امتحان کنید خیلی خوشمزه است"}]},{"word":"die Ausrede","en":"excuse","ru":"отговорка, предлог","vi":"lý do","fa":"بهانه","examples":[{"de":"Das ist doch nur eine Ausrede.","en":"That's just an excuse.","ru":"Это же просто отговорка.","vi":"Đó chỉ là một cái cớ.","fa":"این فقط یک بهانه است."},{"de":"Er hatte immer eine gute Ausrede parat.","en":"He always had a good excuse ready.","ru":"У него всегда была наготове хорошая отговорка.","vi":"Anh ấy luôn chuẩn bị sẵn một lý do chính đáng.","fa":"او همیشه یک بهانه خوب آماده کرده بود."},{"de":"Such dir keine Ausrede, komm einfach mit.","en":"Don't look for an excuse, just come along.","ru":"Не ищи отговорок, просто пойдём с нами.","vi":"Đừng bào chữa nữa, hãy đi với tôi.","fa":"بهانه نیاور، فقط با من بیا."}]},{"word":"ausreichen","en":"to be sufficient, enough","ru":"быть достаточным, хватать","vi":"đủ","fa":"کافی","examples":[{"de":"Das Geld reicht leider nicht für den Urlaub aus.","en":"Unfortunately the money isn't enough for the vacation.","ru":"Денег, к сожалению, не хватает на отпуск.","vi":"Thật không may là không có đủ tiền cho kỳ nghỉ.","fa":"متأسفانه پول کافی برای تعطیلات وجود ندارد."},{"de":"Zwei Stunden reichen für diese Aufgabe völlig aus.","en":"Two hours are completely sufficient for this task.","ru":"Двух часов вполне достаточно для этого задания.","vi":"Hai giờ là hoàn toàn đủ cho nhiệm vụ này.","fa":"دو ساعت برای این کار کاملاً کافی است."}]},{"word":"ausreichend","en":"sufficient; enough","ru":"достаточный","vi":"đủ","fa":"کافی","examples":[{"de":"Wir haben ausreichend Zeit für die Aufgabe.","en":"We have sufficient time for the task.","ru":"У нас достаточно времени на задание.","vi":"Chúng tôi có đủ thời gian cho nhiệm vụ.","fa":"ما زمان کافی برای انجام وظیفه داریم."},{"de":"Das Licht ist zum Lesen nicht ausreichend.","en":"The light is not sufficient for reading.","ru":"Света недостаточно для чтения.","vi":"Ánh sáng không đủ để đọc.","fa":"نور برای خواندن کافی نیست."}]},{"word":"ausrichten","en":"to pass on (a message); to align","ru":"передавать (сообщение); выравнивать","vi":"căn chỉnh","fa":"تراز کردن","examples":[{"de":"Können Sie ihm bitte ausrichten, dass ich angerufen habe?","en":"Could you please tell him that I called?","ru":"Не могли бы вы передать ему, что я звонил?","vi":"Bạn có thể vui lòng nói với anh ấy là tôi đã gọi điện không?","fa":"میشه لطفا بهش بگی زنگ زدم؟"},{"de":"Die Bilder an der Wand sind gerade ausgerichtet.","en":"The pictures on the wall are aligned straight.","ru":"Картины на стене выровнены ровно.","vi":"Những bức tranh trên tường đều thẳng tắp.","fa":"تصاویر روی دیوار مستقیم هستند."}]},{"word":"ausrutschen","en":"to slip","ru":"поскользнуться","vi":"trượt","fa":"لغزش","examples":[{"de":"Pass auf, dass du auf dem Eis nicht ausrutschst.","en":"Be careful not to slip on the ice.","ru":"Осторожно, не поскользнись на льду.","vi":"Hãy cẩn thận để không bị trượt trên băng.","fa":"مراقب باشید روی یخ لیز نخورید."},{"de":"Sie ist im Bad ausgerutscht und hingefallen.","en":"She slipped in the bathroom and fell down.","ru":"Она поскользнулась в ванной и упала.","vi":"Cô bị trượt chân và ngã trong phòng tắm.","fa":"لیز خورد و در حمام افتاد."},{"de":"Auf dem nassen Boden kann man leicht ausrutschen.","en":"On the wet floor one can easily slip.","ru":"На мокром полу легко поскользнуться.","vi":"Thật dễ dàng để trượt trên sàn ướt.","fa":"لیز خوردن روی زمین خیس آسان است."}]},{"word":"aussagekräftig","en":"meaningful, informative","ru":"показательный, содержательный (о данных)","vi":"có ý nghĩa","fa":"معنی دار","examples":[{"de":"Das Ergebnis ist statistisch aussagekräftig.","en":"The result is statistically meaningful.","ru":"Результат статистически показателен.","vi":"Kết quả có ý nghĩa thống kê.","fa":"نتیجه از نظر آماری معنادار است."},{"de":"Eine größere Stichprobe ist aussagekräftiger.","en":"A larger sample is more meaningful.","ru":"Более крупная выборка более показательна.","vi":"Một mẫu lớn hơn có ý nghĩa hơn.","fa":"نمونه بزرگتر معنادارتر است."},{"de":"Diese Grafik ist klar und aussagekräftig.","en":"This graph is clear and informative.","ru":"Этот график ясен и содержателен.","vi":"Đồ họa này rõ ràng và có ý nghĩa.","fa":"این گرافیک واضح و معنادار است."}]},{"word":"ausschließen","en":"to exclude, rule out","ru":"исключать","vi":"loại trừ","fa":"حذف کردن","examples":[{"de":"Wir können einen Fehler nicht ausschließen.","en":"We cannot rule out a mistake.","ru":"Мы не можем исключить ошибку.","vi":"Chúng tôi không thể loại trừ một lỗi.","fa":"ما نمی توانیم یک خطا را رد کنیم."},{"de":"Der Verein hat das Mitglied wegen seines Verhaltens ausgeschlossen.","en":"The club excluded the member because of his behavior.","ru":"Клуб исключил члена из-за его поведения.","vi":"Câu lạc bộ đã trục xuất thành viên đó vì hành vi của anh ta.","fa":"باشگاه این عضو را به دلیل رفتارش اخراج کرد."}]},{"word":"ausschließlich","en":"exclusively, only","ru":"исключительно, только","vi":"độc quyền","fa":"منحصرا","examples":[{"de":"Dieses Angebot gilt ausschließlich für Neukunden.","en":"This offer applies exclusively to new customers.","ru":"Это предложение действует исключительно для новых клиентов.","vi":"Ưu đãi này chỉ có giá trị cho khách hàng mới.","fa":"این پیشنهاد فقط برای مشتریان جدید معتبر است."},{"de":"Er isst ausschließlich vegetarisches Essen.","en":"He eats exclusively vegetarian food.","ru":"Он ест исключительно вегетарианскую пищу.","vi":"Anh ấy chỉ ăn đồ chay.","fa":"او فقط غذای گیاهی می خورد."}]},{"word":"aussehen","en":"to look, appear","ru":"выглядеть","vi":"nhìn","fa":"نگاه کن","examples":[{"de":"Du siehst heute müde aus.","en":"You look tired today.","ru":"Ты сегодня выглядишь уставшим.","vi":"Hôm nay trông bạn có vẻ mệt mỏi.","fa":"امروز خسته به نظر میرسی"},{"de":"Das Essen sieht sehr lecker aus.","en":"The food looks very delicious.","ru":"Еда выглядит очень вкусно.","vi":"Thức ăn trông rất ngon.","fa":"غذا بسیار خوشمزه به نظر می رسد."}]},{"word":"außen","en":"outside, exterior","ru":"снаружи","vi":"bên ngoài","fa":"خارج","examples":[{"de":"Das Haus ist außen weiß gestrichen.","en":"The house is painted white on the outside.","ru":"Дом снаружи покрашен в белый цвет.","vi":"Ngôi nhà được sơn màu trắng ở bên ngoài.","fa":"بیرون خانه سفید رنگ شده است."},{"de":"Von außen sieht das Gebäude sehr modern aus.","en":"From the outside, the building looks very modern.","ru":"Снаружи здание выглядит очень современным.","vi":"Nhìn từ bên ngoài tòa nhà trông rất hiện đại.","fa":"از بیرون ساختمان بسیار مدرن به نظر می رسد."}]},{"word":"außer","en":"except, besides","ru":"кроме","vi":"ngoại trừ","fa":"جز","examples":[{"de":"Alle waren pünktlich außer ihm.","en":"Everyone was on time except him.","ru":"Все были вовремя, кроме него.","vi":"Mọi người đều đúng giờ ngoại trừ anh ấy.","fa":"همه سر وقت بودند جز او."},{"de":"Außer Kaffee trinke ich nichts am Morgen.","en":"Besides coffee, I don't drink anything in the morning.","ru":"Кроме кофе, я утром ничего не пью.","vi":"Tôi không uống gì vào buổi sáng ngoại trừ cà phê.","fa":"صبح ها جز قهوه چیزی نمی نوشم."}]},{"word":"außerdem","en":"besides, moreover","ru":"кроме того","vi":"ngoài ra","fa":"علاوه بر این","examples":[{"de":"Ich habe keine Zeit, außerdem bin ich müde.","en":"I don't have time, besides I'm tired.","ru":"У меня нет времени, кроме того, я устал.","vi":"Tôi không có thời gian và tôi mệt mỏi.","fa":"وقت ندارم و خسته ام."},{"de":"Die Wohnung ist günstig und außerdem sehr zentral gelegen.","en":"The apartment is cheap and, moreover, very centrally located.","ru":"Квартира недорогая и, кроме того, расположена очень центрально.","vi":"Căn hộ giá rẻ và cũng có vị trí rất trung tâm.","fa":"آپارتمان ارزان است و همچنین در مرکز قرار دارد."}]},{"word":"äußerlich","en":"external, outward","ru":"внешний, наружный","vi":"bên ngoài","fa":"خارجی","examples":[{"de":"Diese Salbe ist nur zur äußerlichen Anwendung.","en":"This ointment is for external use only.","ru":"Эта мазь только для наружного применения.","vi":"Thuốc mỡ này chỉ dành cho sử dụng bên ngoài.","fa":"این پماد فقط برای استفاده خارجی است."},{"de":"Äußerlich wirkte er ruhig, doch innerlich war er nervös.","en":"Outwardly he seemed calm, but inwardly he was nervous.","ru":"Внешне он казался спокойным, но внутри нервничал.","vi":"Bề ngoài anh có vẻ bình tĩnh nhưng bên trong lại rất lo lắng.","fa":"از بیرون آرام به نظر می رسید، اما در باطن عصبی بود."},{"de":"Äußerliche Verletzungen heilen meist schneller.","en":"External injuries usually heal more quickly.","ru":"Внешние повреждения обычно заживают быстрее.","vi":"Chấn thương bên ngoài thường lành nhanh hơn.","fa":"جراحات خارجی معمولا سریعتر بهبود می یابند."}]},{"word":"die Aussicht","en":"view; prospect","ru":"вид; перспектива","vi":"quan điểm","fa":"نمای","examples":[{"de":"Von diesem Berg hat man eine wunderschöne Aussicht.","en":"From this mountain you have a wonderful view.","ru":"С этой горы открывается прекрасный вид.","vi":"Có một cái nhìn đẹp từ ngọn núi này.","fa":"منظره زیبایی از این کوه وجود دارد."},{"de":"Er hat gute Aussichten auf den neuen Job.","en":"He has good prospects for the new job.","ru":"У него хорошие перспективы получить новую работу.","vi":"Anh ấy có triển vọng tốt cho công việc mới.","fa":"او چشم اندازهای خوبی برای شغل جدید دارد."}]},{"word":"die Aussprache","en":"pronunciation","ru":"произношение","vi":"cách phát âm","fa":"تلفظ","examples":[{"de":"Deine deutsche Aussprache ist schon sehr gut.","en":"Your German pronunciation is already very good.","ru":"Твоё немецкое произношение уже очень хорошее.","vi":"Phát âm tiếng Đức của bạn rất tốt.","fa":"تلفظ آلمانی شما خیلی خوب است."},{"de":"Die richtige Aussprache lernt man durch viel Üben.","en":"You learn correct pronunciation through a lot of practice.","ru":"Правильное произношение осваивают, много упражняясь.","vi":"Bạn học cách phát âm chính xác thông qua rất nhiều thực hành.","fa":"شما با تمرین زیاد تلفظ صحیح را یاد می گیرید."},{"de":"Bei diesem Wort fällt mir die Aussprache schwer.","en":"I find the pronunciation of this word difficult.","ru":"Произношение этого слова даётся мне трудно.","vi":"Từ này đối với tôi thật khó phát âm.","fa":"تلفظ این کلمه برای من سخت است."}]},{"word":"aussprechen","en":"to pronounce; to express","ru":"произносить; высказывать","vi":"phát âm","fa":"تلفظ کنید","examples":[{"de":"Wie spricht man dieses Wort aus?","en":"How do you pronounce this word?","ru":"Как произносится это слово?","vi":"Bạn phát âm từ này như thế nào?","fa":"چگونه این کلمه را تلفظ می کنید؟"},{"de":"Sie spricht ihre Meinung immer offen aus.","en":"She always expresses her opinion openly.","ru":"Она всегда открыто высказывает своё мнение.","vi":"Cô ấy luôn nói ra suy nghĩ của mình một cách cởi mở.","fa":"او همیشه نظر خود را آشکارا بیان می کند."}]},{"word":"ausstehend","en":"outstanding; pending","ru":"неоплаченный, невыплаченный; ожидаемый, ещё не решённый","vi":"đang chờ xử lý","fa":"در انتظار","examples":[{"de":"Die ausstehende Rechnung muss bald bezahlt werden.","en":"The outstanding invoice must be paid soon.","ru":"Неоплаченный счёт нужно вскоре оплатить.","vi":"Hóa đơn còn nợ phải được thanh toán sớm.","fa":"فاکتور معوقه باید به زودی پرداخت شود."},{"de":"Es gibt noch einige ausstehende Fragen.","en":"There are still some pending questions.","ru":"Есть ещё несколько нерешённых вопросов.","vi":"Vẫn còn một số câu hỏi nổi bật.","fa":"هنوز چند سوال باقی مانده است."},{"de":"Die ausstehende Antwort macht mich nervös.","en":"The pending answer makes me nervous.","ru":"Ожидаемый ответ заставляет меня нервничать.","vi":"Câu trả lời đang chờ xử lý khiến tôi lo lắng.","fa":"پاسخ در انتظار من را عصبی می کند."}]},{"word":"ausstellen","en":"to exhibit; to issue (a document)","ru":"выставлять; выдавать (документ)","vi":"triển lãm","fa":"نمایشگاه","examples":[{"de":"Das Museum stellt moderne Kunst aus.","en":"The museum exhibits modern art.","ru":"Музей выставляет современное искусство.","vi":"Bảo tàng trưng bày nghệ thuật hiện đại.","fa":"این موزه هنر مدرن را به نمایش می گذارد."},{"de":"Das Amt stellt einen neuen Reisepass aus.","en":"The office issues a new passport.","ru":"Ведомство выдаёт новый паспорт.","vi":"Văn phòng cấp hộ chiếu mới.","fa":"اداره یک پاسپورت جدید صادر می کند."}]},{"word":"die Ausstellung","en":"exhibition","ru":"выставка","vi":"cuộc triển lãm","fa":"نمایشگاه","examples":[{"de":"Die Ausstellung im Museum ist noch bis Mai zu sehen.","en":"The exhibition at the museum runs until May.","ru":"Выставку в музее можно посмотреть до мая.","vi":"Triển lãm trong bảo tàng có thể được nhìn thấy cho đến tháng Năm.","fa":"این نمایشگاه در موزه تا ماه می قابل مشاهده است."},{"de":"Wir haben in der Ausstellung viele Bilder gesehen.","en":"We saw many paintings at the exhibition.","ru":"На выставке мы увидели много картин.","vi":"Chúng tôi đã xem nhiều bức tranh trong triển lãm.","fa":"تصاویر زیادی در نمایشگاه دیدیم."}]},{"word":"aussterben","en":"to die out, to become extinct","ru":"вымирать","vi":"tuyệt chủng","fa":"منقرض شده","examples":[{"de":"Viele Tierarten sterben wegen des Klimawandels aus.","en":"Many animal species are dying out because of climate change.","ru":"Многие виды животных вымирают из-за изменения климата.","vi":"Nhiều loài động vật đang bị tuyệt chủng do biến đổi khí hậu.","fa":"بسیاری از گونه های جانوری به دلیل تغییرات آب و هوایی در حال انقراض هستند."},{"de":"Wenn der Lebensraum verschwindet, sterben die Tiere aus.","en":"When the habitat disappears, the animals become extinct.","ru":"Когда среда обитания исчезает, животные вымирают.","vi":"Khi môi trường sống biến mất, các loài động vật chết dần.","fa":"هنگامی که زیستگاه ناپدید می شود، حیوانات می میرند."},{"de":"Der Eisbär könnte in einigen Regionen bald aussterben.","en":"The polar bear could soon become extinct in some regions.","ru":"Белый медведь в некоторых регионах может скоро вымереть.","vi":"Gấu Bắc Cực có thể sớm bị tuyệt chủng ở một số vùng.","fa":"خرس قطبی ممکن است به زودی در برخی مناطق منقرض شود."}]},{"word":"der Ausstoß","en":"emission, output","ru":"выброс, выделение","vi":"đầu ra","fa":"خروجی","examples":[{"de":"Der Ausstoß von Treibhausgasen muss sinken.","en":"The emission of greenhouse gases must fall.","ru":"Выброс парниковых газов должен снизиться.","vi":"Phát thải khí nhà kính phải giảm","fa":"انتشار گازهای گلخانه ای باید کاهش یابد."},{"de":"Elektroautos haben keinen Ausstoß von Abgasen.","en":"Electric cars have no exhaust emissions.","ru":"У электромобилей нет выхлопных выбросов.","vi":"Ô tô điện không thải ra bất kỳ khí thải nào.","fa":"خودروهای برقی هیچ گاز خروجی از اگزوز ساطع نمی کنند."},{"de":"Die Fabrik hat ihren Ausstoß deutlich verringert.","en":"The factory has significantly reduced its emissions.","ru":"Фабрика значительно сократила свои выбросы.","vi":"Nhà máy đã giảm sản lượng đáng kể.","fa":"این کارخانه تولید خود را به میزان قابل توجهی کاهش داده است."}]},{"word":"aussuchen","en":"to pick out; to choose","ru":"выбирать, отбирать","vi":"chọn","fa":"انتخاب کنید","examples":[{"de":"Such dir ein Geschenk aus, das dir gefällt.","en":"Pick out a present that you like.","ru":"Выбери подарок, который тебе нравится.","vi":"Hãy chọn một món quà mà bạn thích.","fa":"هدیه ای را که دوست دارید انتخاب کنید."},{"de":"Wir haben das Hotel sorgfältig ausgesucht.","en":"We carefully picked out the hotel.","ru":"Мы тщательно выбирали отель.","vi":"Chúng tôi đã chọn khách sạn một cách cẩn thận.","fa":"هتل را با دقت انتخاب کردیم."},{"de":"Sie sucht für die Party ein schönes Kleid aus.","en":"She is choosing a nice dress for the party.","ru":"Она выбирает красивое платье для праздника.","vi":"Cô chọn một chiếc váy đẹp cho bữa tiệc.","fa":"او یک لباس زیبا برای مهمانی انتخاب می کند."}]},{"word":"die Auswahl","en":"selection, choice (range)","ru":"выбор, ассортимент","vi":"sự lựa chọn","fa":"انتخاب","examples":[{"de":"Im Laden gibt es eine große Auswahl an Brot.","en":"In the shop there is a wide selection of bread.","ru":"В магазине большой выбор хлеба.","vi":"Có rất nhiều lựa chọn bánh mì trong cửa hàng.","fa":"در فروشگاه تعداد زیادی نان وجود دارد."},{"de":"Die Auswahl fiel mir gar nicht leicht.","en":"The choice was not at all easy for me.","ru":"Выбор дался мне совсем не легко.","vi":"Sự lựa chọn không hề dễ dàng với tôi chút nào.","fa":"انتخاب برای من اصلا آسان نبود."},{"de":"Triff bitte eine Auswahl bis morgen.","en":"Please make a selection by tomorrow.","ru":"Сделай, пожалуйста, выбор до завтра.","vi":"Hãy thực hiện lựa chọn vào ngày mai.","fa":"لطفا تا فردا انتخاب کنید"}]},{"word":"auswählen","en":"to select, choose","ru":"выбирать","vi":"chọn","fa":"انتخاب کنید","examples":[{"de":"Bitte wählen Sie eine Option aus dem Menü aus.","en":"Please select an option from the menu.","ru":"Пожалуйста, выберите вариант из меню.","vi":"Vui lòng chọn một tùy chọn từ menu.","fa":"لطفاً یک گزینه را از منو انتخاب کنید."},{"de":"Der Trainer wählt die besten Spieler für das Team aus.","en":"The coach selects the best players for the team.","ru":"Тренер выбирает лучших игроков для команды.","vi":"Huấn luyện viên chọn những cầu thủ tốt nhất cho đội.","fa":"مربی بهترین بازیکنان را برای تیم انتخاب می کند."}]},{"word":"der Ausweis","en":"ID card","ru":"удостоверение личности","vi":"the ID card","fa":"کارت شناسایی","examples":[{"de":"Können Sie mir bitte Ihren Ausweis zeigen?","en":"Could you please show me your ID?","ru":"Не могли бы вы показать мне удостоверение личности?","vi":"Bạn có thể cho tôi xem ID của bạn được không?","fa":"لطفا شناسنامه خود را به من نشان دهید؟"},{"de":"Ich habe meinen Ausweis leider zu Hause vergessen.","en":"Unfortunately I forgot my ID at home.","ru":"К сожалению, я забыл удостоверение личности дома.","vi":"Thật không may, tôi quên CMND ở nhà.","fa":"متاسفانه شناسنامه ام را در خانه فراموش کردم."}]},{"word":"auswendig","en":"by heart; from memory","ru":"наизусть, по памяти","vi":"thuộc lòng","fa":"با قلب","examples":[{"de":"Ich kenne dieses Gedicht auswendig.","en":"I know this poem by heart.","ru":"Я знаю это стихотворение наизусть.","vi":"Tôi thuộc lòng bài thơ này.","fa":"من این شعر را از صمیم قلب می دانم."},{"de":"Kannst du die Telefonnummer auswendig?","en":"Do you know the telephone number by heart?","ru":"Ты знаешь номер телефона наизусть?","vi":"Bạn có thuộc lòng số điện thoại không?","fa":"آیا شماره تلفن را از روی قلب می دانید؟"},{"de":"Die Schauspielerin lernte ihren Text auswendig.","en":"The actress learned her lines by heart.","ru":"Актриса выучила свои реплики наизусть.","vi":"Nữ diễn viên đã học thuộc lòng lời thoại của mình.","fa":"این بازیگر خط های خود را از زبان یاد گرفت."}]},{"word":"auswerten","en":"to evaluate, to analyse","ru":"анализировать, обрабатывать (данные)","vi":"đánh giá","fa":"ارزیابی کنید","examples":[{"de":"Wir werten die Ergebnisse der Umfrage aus.","en":"We are evaluating the results of the survey.","ru":"Мы анализируем результаты опроса.","vi":"Chúng tôi đánh giá kết quả của cuộc khảo sát.","fa":"ما نتایج نظرسنجی را ارزیابی می کنیم."},{"de":"Das Programm wertet die Daten automatisch aus.","en":"The program analyses the data automatically.","ru":"Программа анализирует данные автоматически.","vi":"Chương trình sẽ tự động đánh giá dữ liệu.","fa":"برنامه به طور خودکار داده ها را ارزیابی می کند."},{"de":"Bevor wir entscheiden, werten wir alle Zahlen aus.","en":"Before we decide, we evaluate all the figures.","ru":"Прежде чем решить, мы анализируем все цифры.","vi":"Trước khi đưa ra quyết định, chúng tôi đánh giá tất cả các con số.","fa":"قبل از تصمیم گیری، همه اعداد را ارزیابی می کنیم."}]},{"word":"die Auswertung","en":"evaluation, analysis (of data)","ru":"обработка, анализ (данных)","vi":"sự đánh giá","fa":"ارزیابی","examples":[{"de":"Die Auswertung der Umfrage dauert mehrere Tage.","en":"The evaluation of the survey takes several days.","ru":"Обработка опроса занимает несколько дней.","vi":"Việc đánh giá cuộc khảo sát mất vài ngày.","fa":"ارزیابی نظرسنجی چند روز طول می کشد."},{"de":"Nach der Auswertung zeigen wir die Ergebnisse in einem Diagramm.","en":"After the analysis we show the results in a chart.","ru":"После анализа мы показываем результаты на диаграмме.","vi":"Sau khi đánh giá, chúng tôi hiển thị kết quả dưới dạng biểu đồ.","fa":"پس از ارزیابی، نتایج را در نمودار نشان می دهیم."},{"de":"Die statistische Auswertung war eindeutig.","en":"The statistical evaluation was clear.","ru":"Статистический анализ был однозначным.","vi":"Phân tích thống kê rõ ràng.","fa":"تجزیه و تحلیل آماری واضح بود."}]},{"word":"die Auswirkung","en":"effect; impact","ru":"воздействие; последствие","vi":"tác động","fa":"تاثیر","examples":[{"de":"Die Auswirkungen der Krise sind noch heute zu spüren.","en":"The effects of the crisis can still be felt today.","ru":"Последствия кризиса ощущаются и сегодня.","vi":"Những ảnh hưởng của cuộc khủng hoảng vẫn có thể được cảm nhận cho đến ngày nay.","fa":"اثرات این بحران هنوز هم امروز قابل احساس است."},{"de":"Zu wenig Schlaf hat negative Auswirkungen auf die Konzentration.","en":"Too little sleep has a negative impact on concentration.","ru":"Недостаток сна негативно влияет на концентрацию.","vi":"Ngủ quá ít có tác động tiêu cực đến khả năng tập trung.","fa":"خواب کم تاثیر منفی بر تمرکز دارد."}]},{"word":"ausziehen","en":"to move out; to take off (clothes)","ru":"съезжать; снимать (одежду)","vi":"cất cánh","fa":"برخاستن","examples":[{"de":"Wir ziehen nächsten Monat aus dieser Wohnung aus.","en":"We are moving out of this apartment next month.","ru":"В следующем месяце мы съезжаем из этой квартиры.","vi":"Chúng tôi sẽ chuyển khỏi căn hộ này vào tháng tới.","fa":"ماه آینده از این آپارتمان نقل مکان می کنیم."},{"de":"Zieh bitte deine nassen Schuhe aus.","en":"Please take off your wet shoes.","ru":"Пожалуйста, сними свои мокрые ботинки.","vi":"Hãy cởi giày ướt của bạn ra.","fa":"لطفا کفش های خیس خود را در بیاورید."}]},{"word":"das Auto","en":"car","ru":"автомобиль, машина","vi":"chiếc xe","fa":"ماشین","examples":[{"de":"Wir fahren mit dem Auto in den Urlaub.","en":"We are driving to our vacation by car.","ru":"Мы едем в отпуск на машине.","vi":"Chúng tôi đang đi nghỉ bằng ô tô.","fa":"ما با ماشین به تعطیلات می رویم."},{"de":"Sein neues Auto ist sehr schnell.","en":"His new car is very fast.","ru":"Его новая машина очень быстрая.","vi":"Chiếc xe mới của anh ấy chạy rất nhanh.","fa":"ماشین جدیدش خیلی سریعه."}]},{"word":"der Automat","en":"vending machine","ru":"автомат (торговый)","vi":"cái máy","fa":"دستگاه","examples":[{"de":"Am Automaten kann man Fahrkarten kaufen.","en":"You can buy tickets at the vending machine.","ru":"В автомате можно купить билеты.","vi":"You can buy tickets at the machine.","fa":"شما می توانید بلیط را از دستگاه خریداری کنید."},{"de":"Der Getränkeautomat ist leider kaputt.","en":"The drinks vending machine is unfortunately broken.","ru":"Автомат с напитками, к сожалению, сломан.","vi":"Thật không may, máy đồ uống bị hỏng.","fa":"متاسفانه دستگاه نوشیدنی خراب است."}]},{"word":"der Autor","en":"author","ru":"автор","vi":"tác giả","fa":"نویسنده","examples":[{"de":"Der Autor dieses Romans ist sehr bekannt.","en":"The author of this novel is very well known.","ru":"Автор этого романа очень известен.","vi":"Tác giả cuốn tiểu thuyết này rất nổi tiếng.","fa":"نویسنده این رمان بسیار شناخته شده است."},{"de":"Sie liest gern Bücher von diesem Autor.","en":"She likes reading books by this author.","ru":"Она любит читать книги этого автора.","vi":"Cô ấy thích đọc sách của tác giả này.","fa":"او از خواندن کتاب های این نویسنده لذت می برد."}]},{"word":"das Autorennen","en":"car race","ru":"автогонки","vi":"cuộc đua xe","fa":"مسابقه اتومبیل رانی","examples":[{"de":"Am Wochenende findet ein großes Autorennen statt.","en":"A big car race takes place at the weekend.","ru":"На выходных состоятся большие автогонки.","vi":"Có một cuộc đua xe lớn diễn ra vào cuối tuần.","fa":"آخر هفته یک مسابقه اتومبیلرانی بزرگ در حال برگزاری است."},{"de":"Mein Vater schaut sich gern jedes Autorennen an.","en":"My father likes to watch every car race.","ru":"Мой отец охотно смотрит любые автогонки.","vi":"Bố tôi thích xem mọi cuộc đua xe.","fa":"پدرم دوست دارد هر مسابقه اتومبیل رانی تماشا کند."},{"de":"Beim Autorennen waren die Wagen unglaublich schnell.","en":"At the car race the cars were incredibly fast.","ru":"На автогонках машины были невероятно быстрыми.","vi":"Trong các cuộc đua ô tô, những chiếc xe chạy cực kỳ nhanh.","fa":"در مسابقات اتومبیل رانی، اتومبیل ها فوق العاده سریع بودند."}]},{"word":"die Autorin","en":"author (female)","ru":"автор (ж.)","vi":"tác giả","fa":"نویسنده","examples":[{"de":"Die Autorin hat für ihr Buch einen Preis gewonnen.","en":"The author won a prize for her book.","ru":"Автор получила премию за свою книгу.","vi":"Tác giả đã giành được giải thưởng cho cuốn sách của mình.","fa":"نویسنده برای کتابش جایزه گرفت."},{"de":"Diese Autorin ist in vielen Ländern bekannt.","en":"This author is known in many countries.","ru":"Эта писательница известна во многих странах.","vi":"Tác giả này được biết đến ở nhiều nước.","fa":"این نویسنده در بسیاری از کشورها شناخته شده است."},{"de":"Die Autorin signierte nach der Lesung ihre Bücher.","en":"The author signed her books after the reading.","ru":"После чтения автор подписывала свои книги.","vi":"Tác giả đã ký tặng sách của mình sau khi đọc.","fa":"نویسنده پس از خواندن کتاب های خود را امضا کرد."}]},{"word":"der (Back-)Ofen","en":"oven","ru":"духовка; печь","vi":"lò nướng (nướng)","fa":"فر (پخت)","examples":[{"de":"Der Kuchen ist noch im Ofen.","en":"The cake is still in the oven.","ru":"Пирог ещё в духовке.","vi":"Bánh vẫn còn trong lò.","fa":"کیک هنوز در فر است."},{"de":"Heiz den Ofen auf 180 Grad vor.","en":"Preheat the oven to 180 degrees.","ru":"Разогрей духовку до 180 градусов.","vi":"Làm nóng lò ở 180 độ.","fa":"فر را با دمای 180 درجه گرم کنید."}]},{"word":"das (Back-)Rohr","en":"oven","ru":"духовка","vi":"ống (nướng)","fa":"لوله (پخت)","examples":[{"de":"Der Kuchen muss noch 20 Minuten im Backrohr bleiben.","en":"The cake still needs to stay in the oven for 20 minutes.","ru":"Пирог должен ещё 20 минут постоять в духовке.","vi":"Bánh cần để trong lò thêm 20 phút nữa.","fa":"کیک باید 20 دقیقه دیگر در فر بماند."},{"de":"Heiz das Rohr auf 180 Grad vor.","en":"Preheat the oven to 180 degrees.","ru":"Разогрей духовку до 180 градусов.","vi":"Làm nóng ống ở nhiệt độ 180 độ.","fa":"لوله را تا 180 درجه از قبل گرم کنید."}]},{"word":"backen","en":"to bake","ru":"печь, выпекать","vi":"nướng","fa":"پختن","examples":[{"de":"Meine Mutter backt jeden Sonntag einen Kuchen.","en":"My mother bakes a cake every Sunday.","ru":"Моя мама печёт торт каждое воскресенье.","vi":"Mẹ tôi nướng bánh vào mỗi chủ nhật.","fa":"مادرم هر یکشنبه یک کیک می پزد."},{"de":"Wir backen zu Weihnachten Plätzchen.","en":"We bake cookies at Christmas.","ru":"На Рождество мы печём печенье.","vi":"Chúng tôi nướng bánh cho Giáng sinh.","fa":"ما برای کریسمس شیرینی می پزمیم."}]},{"word":"die Bäckerei","en":"bakery","ru":"пекарня, булочная","vi":"tiệm bánh","fa":"نانوایی","examples":[{"de":"Frühmorgens duftet es in der ganzen Bäckerei nach frischem Brot.","en":"Early in the morning the whole bakery smells of fresh bread.","ru":"Ранним утром во всей пекарне пахнет свежим хлебом.","vi":"Sáng sớm cả tiệm bánh thơm mùi bánh mì mới nướng.","fa":"صبح زود کل نانوایی بوی نان تازه می دهد."},{"de":"Ich hole jeden Sonntag Brötchen aus der Bäckerei.","en":"I get rolls from the bakery every Sunday.","ru":"Каждое воскресенье я беру булочки в пекарне.","vi":"Tôi nhận được bánh mì từ tiệm bánh vào mỗi Chủ Nhật.","fa":"من هر یکشنبه از نانوایی رول می گیرم."},{"de":"Die kleine Bäckerei an der Ecke hat den besten Kuchen.","en":"The little bakery on the corner has the best cake.","ru":"У маленькой пекарни на углу лучший пирог.","vi":"Tiệm bánh nhỏ ở góc phố có những chiếc bánh ngon nhất.","fa":"نانوایی کوچک گوشه ای بهترین کیک ها را دارد."}]},{"word":"die Backmischung","en":"baking mix","ru":"смесь для выпечки","vi":"hỗn hợp nướng","fa":"مخلوط پخت","examples":[{"de":"Mit dieser Backmischung gelingt der Kuchen ganz leicht.","en":"With this baking mix the cake turns out easily.","ru":"С этой смесью для выпечки пирог получается совсем легко.","vi":"Với cách làm bánh này, việc trộn bánh rất dễ dàng.","fa":"با این مخلوط پخت کیک بسیار آسان است."},{"de":"Die Backmischung braucht nur ein Ei und etwas Milch.","en":"The baking mix only needs one egg and a little milk.","ru":"Для смеси для выпечки нужно только одно яйцо и немного молока.","vi":"Hỗn hợp làm bánh chỉ cần một quả trứng và một ít sữa.","fa":"مخلوط پخت فقط به یک تخم مرغ و کمی شیر نیاز دارد."},{"de":"Wir kauften eine Backmischung für Schokokekse.","en":"We bought a baking mix for chocolate biscuits.","ru":"Мы купили смесь для выпечки шоколадного печенья.","vi":"Chúng tôi đã mua hỗn hợp bánh quy sô-cô-la chip.","fa":"ما یک مخلوط کوکی چیپسی شکلاتی خریدیم."}]},{"word":"das Backrohr","en":"oven (Austrian)","ru":"духовка (австр.)","vi":"lò nướng","fa":"فر","examples":[{"de":"Stell den Kuchen bitte ins Backrohr.","en":"Please put the cake in the oven.","ru":"Поставь, пожалуйста, пирог в духовку.","vi":"Vui lòng cho bánh vào lò nướng.","fa":"لطفا کیک را در فر قرار دهید."},{"de":"Das Backrohr muss zuerst vorgeheizt werden.","en":"The oven has to be preheated first.","ru":"Духовку нужно сначала разогреть.","vi":"Lò nướng phải được làm nóng trước.","fa":"ابتدا فر باید از قبل گرم شود."},{"de":"Vorsicht, das Backrohr ist sehr heiß!","en":"Careful, the oven is very hot!","ru":"Осторожно, духовка очень горячая!","vi":"Hãy cẩn thận, lò rất nóng!","fa":"مراقب باشید فر خیلی داغ است!"}]},{"word":"baden","en":"to bathe, swim","ru":"купаться","vi":"tắm","fa":"حمام کردن","examples":[{"de":"Im Sommer gehen wir oft im See baden.","en":"In summer we often go swimming in the lake.","ru":"Летом мы часто купаемся в озере.","vi":"Vào mùa hè chúng tôi thường đi bơi ở hồ.","fa":"در تابستان ما اغلب برای شنا در دریاچه می رویم."},{"de":"Das Kind badet gern in der Badewanne.","en":"The child likes bathing in the bathtub.","ru":"Ребёнок любит купаться в ванне.","vi":"Bé thích tắm trong bồn tắm.","fa":"کودک دوست دارد در وان حمام کند."}]},{"word":"die Badewanne","en":"bathtub","ru":"ванна","vi":"bồn tắm","fa":"وان حمام","examples":[{"de":"Nach einem langen Tag liege ich gern in der Badewanne.","en":"After a long day I like to lie in the bathtub.","ru":"После долгого дня я люблю полежать в ванне.","vi":"Sau một ngày dài, tôi thích nằm trong bồn tắm.","fa":"بعد از یک روز طولانی، دوست دارم در وان دراز بکشم."},{"de":"Die Kinder spielen gern in der Badewanne.","en":"The children like to play in the bathtub.","ru":"Дети любят играть в ванне.","vi":"Trẻ em thích chơi trong bồn tắm.","fa":"بچه ها دوست دارند در وان حمام بازی کنند."},{"de":"Unsere neue Badewanne ist viel größer als die alte.","en":"Our new bathtub is much bigger than the old one.","ru":"Наша новая ванна гораздо больше старой.","vi":"Bồn tắm mới của chúng tôi lớn hơn nhiều so với bồn tắm cũ.","fa":"وان جدید ما بسیار بزرگتر از وان قبلی است."}]},{"word":"die Bahn","en":"train, railway","ru":"поезд, железная дорога","vi":"đường sắt","fa":"راه آهن","examples":[{"de":"Ich fahre lieber mit der Bahn als mit dem Auto.","en":"I prefer to travel by train rather than by car.","ru":"Я предпочитаю ездить на поезде, а не на машине.","vi":"Tôi thích đi tàu hơn là đi ô tô.","fa":"ترجیح می دهم با قطار به جای ماشین سوار شوم."},{"de":"Die Bahn hatte heute zwanzig Minuten Verspätung.","en":"The train was twenty minutes late today.","ru":"Поезд сегодня опоздал на двадцать минут.","vi":"Hôm nay tàu trễ hai mươi phút.","fa":"قطار امروز بیست دقیقه تاخیر داشت."}]},{"word":"der Bahnhof","en":"train station","ru":"вокзал","vi":"ga xe lửa","fa":"ایستگاه قطار","examples":[{"de":"Wir treffen uns am Bahnhof um neun Uhr.","en":"We're meeting at the train station at nine o'clock.","ru":"Мы встречаемся на вокзале в девять часов.","vi":"Chúng ta sẽ gặp nhau ở ga xe lửa lúc chín giờ.","fa":"ساعت نه در ایستگاه قطار همدیگر را می بینیم."},{"de":"Der Hauptbahnhof liegt im Zentrum der Stadt.","en":"The main station is located in the city center.","ru":"Главный вокзал находится в центре города.","vi":"Nhà ga xe lửa chính nằm ở trung tâm thành phố.","fa":"ایستگاه اصلی قطار در مرکز شهر قرار دارد."}]},{"word":"der Bahnsteig","en":"platform","ru":"платформа (на вокзале)","vi":"nền tảng","fa":"پلت فرم","examples":[{"de":"Der Zug fährt von Bahnsteig drei ab.","en":"The train departs from platform three.","ru":"Поезд отправляется с третьей платформы.","vi":"Tàu khởi hành từ sân ga số ba.","fa":"قطار از سکوی سه حرکت می کند."},{"de":"Wir warten auf dem Bahnsteig auf den nächsten Zug.","en":"We are waiting on the platform for the next train.","ru":"Мы ждём следующий поезд на платформе.","vi":"Chúng tôi đợi chuyến tàu tiếp theo ở sân ga.","fa":"روی سکو منتظر قطار بعدی هستیم."}]},{"word":"bald","en":"soon","ru":"скоро","vi":"sớm thôi","fa":"به زودی","examples":[{"de":"Ich hoffe, wir sehen uns bald wieder.","en":"I hope we see each other again soon.","ru":"Надеюсь, мы скоро снова увидимся.","vi":"Tôi hy vọng chúng ta sẽ sớm gặp lại nhau.","fa":"امیدوارم به زودی دوباره همدیگر را ببینیم."},{"de":"Der Frühling kommt bald.","en":"Spring is coming soon.","ru":"Весна скоро наступит.","vi":"Mùa xuân đang đến sớm.","fa":"بهار به زودی می آید."}]},{"word":"baldmöglichst","en":"as soon as possible","ru":"как можно скорее","vi":"càng sớm càng tốt","fa":"در اسرع وقت","examples":[{"de":"Bitte rufen Sie mich baldmöglichst zurück.","en":"Please call me back as soon as possible.","ru":"Пожалуйста, перезвони мне как можно скорее.","vi":"Hãy gọi lại cho tôi sớm nhất có thể.","fa":"لطفا در اسرع وقت با من تماس بگیرید."},{"de":"Wir bitten um eine baldmöglichste Antwort.","en":"We ask for a reply as soon as possible.","ru":"Мы просим ответить как можно скорее.","vi":"Chúng tôi yêu cầu một câu trả lời càng sớm càng tốt.","fa":"خواهان پاسخ در اسرع وقت هستیم."},{"de":"Die Unterlagen müssen baldmöglichst eingereicht werden.","en":"The documents must be submitted as soon as possible.","ru":"Документы нужно подать как можно скорее.","vi":"Các tài liệu phải được nộp càng sớm càng tốt.","fa":"مدارک باید در اسرع وقت ارسال شود."}]},{"word":"das Balkendiagramm","en":"bar chart","ru":"столбчатая диаграмма","vi":"biểu đồ thanh","fa":"نمودار میله ای","examples":[{"de":"Das Balkendiagramm zeigt den Umsatz pro Monat.","en":"The bar chart shows the revenue per month.","ru":"Столбчатая диаграмма показывает выручку за месяц.","vi":"Biểu đồ thanh hiển thị doanh số bán hàng mỗi tháng.","fa":"نمودار میله ای فروش در ماه را نشان می دهد."},{"de":"Aus dem Balkendiagramm wird der Unterschied sofort klar.","en":"From the bar chart the difference becomes clear immediately.","ru":"Из столбчатой диаграммы сразу становится ясна разница.","vi":"Sự khác biệt có thể thấy rõ ngay từ biểu đồ thanh.","fa":"تفاوت بلافاصله از نمودار میله ای مشخص می شود."},{"de":"Sie erstellte ein Balkendiagramm für ihre Präsentation.","en":"She created a bar chart for her presentation.","ru":"Она создала столбчатую диаграмму для своей презентации.","vi":"Cô ấy đã tạo một biểu đồ thanh cho bài thuyết trình của mình.","fa":"او یک نمودار میله ای برای ارائه خود ایجاد کرد."}]},{"word":"der Balkon","en":"balcony","ru":"балкон","vi":"ban công","fa":"بالکن","examples":[{"de":"Unsere Wohnung hat einen großen Balkon.","en":"Our apartment has a large balcony.","ru":"В нашей квартире большой балкон.","vi":"Căn hộ của chúng tôi có một ban công rộng.","fa":"آپارتمان ما دارای یک بالکن بزرگ است."},{"de":"Im Sommer frühstücken wir gern auf dem Balkon.","en":"In summer we like to have breakfast on the balcony.","ru":"Летом мы любим завтракать на балконе.","vi":"Vào mùa hè, chúng tôi thích ăn sáng trên ban công.","fa":"در تابستان دوست داریم صبحانه را در بالکن بخوریم."}]},{"word":"der Ball","en":"ball","ru":"мяч","vi":"quả bóng","fa":"توپ","examples":[{"de":"Die Kinder spielen im Park mit einem Ball.","en":"The children are playing with a ball in the park.","ru":"Дети играют мячом в парке.","vi":"Bọn trẻ đang chơi bóng trong công viên.","fa":"بچه ها در پارک با توپ بازی می کنند."},{"de":"Wirf mir bitte den Ball zu.","en":"Please throw me the ball.","ru":"Брось мне мяч, пожалуйста.","vi":"Hãy ném cho tôi quả bóng.","fa":"لطفا توپ را به من پرتاب کن"}]},{"word":"die Ballerina","en":"ballerina","ru":"балерина","vi":"nữ diễn viên ballet","fa":"بالرین","examples":[{"de":"Die Ballerina trug ein weißes Kleid und rosa Schuhe.","en":"The ballerina wore a white dress and pink shoes.","ru":"Балерина была в белом платье и розовых туфельках.","vi":"Nữ diễn viên ballet mặc váy trắng và đi giày màu hồng.","fa":"بالرین یک لباس سفید و کفش صورتی پوشیده بود."},{"de":"Schon als Kind wollte sie Ballerina werden.","en":"Even as a child she wanted to become a ballerina.","ru":"Ещё ребёнком она хотела стать балериной.","vi":"Ngay từ khi còn nhỏ, cô đã muốn trở thành một nữ diễn viên múa ba lê.","fa":"حتی در کودکی می خواست بالرین شود."},{"de":"Die Ballerina balancierte auf den Spitzen ihrer Füße.","en":"The ballerina balanced on the tips of her toes.","ru":"Балерина балансировала на кончиках пальцев.","vi":"Nữ diễn viên ballet giữ thăng bằng trên đầu bàn chân.","fa":"بالرین روی نوک پاهایش تعادل برقرار کرد."}]},{"word":"das Ballett","en":"ballet","ru":"балет","vi":"múa ba lê","fa":"باله","examples":[{"de":"Meine Tochter nimmt seit zwei Jahren Ballettunterricht.","en":"My daughter has been taking ballet lessons for two years.","ru":"Моя дочь уже два года занимается балетом.","vi":"Con gái tôi đã học múa ba lê được hai năm.","fa":"دخترم دو سال است که کلاس باله می‌خواند."},{"de":"Wir haben gestern Abend ein Ballett im Theater gesehen.","en":"We watched a ballet at the theater last night.","ru":"Вчера вечером мы смотрели балет в театре.","vi":"Chúng tôi đã xem một vở ballet ở nhà hát tối qua.","fa":"دیشب یک باله در تئاتر دیدیم."}]},{"word":"die Banane","en":"banana","ru":"банан","vi":"quả chuối","fa":"موز","examples":[{"de":"Ich esse gern eine Banane zum Frühstück.","en":"I like eating a banana for breakfast.","ru":"Я люблю есть банан на завтрак.","vi":"Tôi thích ăn một quả chuối vào bữa sáng.","fa":"من دوست دارم برای صبحانه یک موز بخورم."},{"de":"Die Bananen im Supermarkt waren noch grün.","en":"The bananas at the supermarket were still green.","ru":"Бананы в супермаркете были ещё зелёными.","vi":"Những quả chuối trong siêu thị vẫn còn xanh.","fa":"موزهای سوپرمارکت هنوز سبز بودند."}]},{"word":"der Bancomat","en":"cash machine, ATM (Swiss)","ru":"банкомат (швейц.)","vi":"máy ATM","fa":"دستگاه خودپرداز","examples":[{"de":"In der Schweiz hebe ich Geld am Bancomat ab.","en":"In Switzerland I withdraw money at the cash machine.","ru":"В Швейцарии я снимаю деньги в банкомате.","vi":"Ở Thụy Sĩ tôi rút tiền từ máy ATM.","fa":"در سوئیس از دستگاه خودپرداز پول برداشت می کنم."},{"de":"Der nächste Bancomat ist gleich um die Ecke.","en":"The nearest cash machine is just around the corner.","ru":"Ближайший банкомат сразу за углом.","vi":"Máy ATM tiếp theo ở ngay góc đường.","fa":"دستگاه خودپرداز بعدی نزدیک است."},{"de":"Der Bancomat hat leider kein Bargeld mehr.","en":"The cash machine unfortunately has no more cash.","ru":"В банкомате, к сожалению, больше нет наличных.","vi":"Thật không may, máy ATM không còn tiền mặt nữa.","fa":"متأسفانه دستگاه خودپرداز دیگر پول نقد ندارد."}]},{"word":"der Bancomat/Bankomat","en":"ATM","ru":"банкомат","vi":"ATM/ATM","fa":"ATM/ATM","examples":[{"de":"Ich hebe am Bankomat schnell etwas Bargeld ab.","en":"I quickly withdraw some cash at the ATM.","ru":"Я быстро снимаю наличные в банкомате.","vi":"Tôi nhanh chóng rút một ít tiền mặt từ máy ATM.","fa":"سریع مقداری پول نقد از خودپرداز برداشت می کنم."},{"de":"Der nächste Bancomat ist gleich um die Ecke.","en":"The nearest ATM is just around the corner.","ru":"Ближайший банкомат находится прямо за углом.","vi":"Máy ATM tiếp theo ở ngay góc đường.","fa":"دستگاه خودپرداز بعدی نزدیک است."}]},{"word":"die Bancomatkarte","en":"bank card, debit card (Swiss)","ru":"банковская (дебетовая) карта (швейц.)","vi":"thẻ ATM","fa":"کارت خودپرداز","examples":[{"de":"Mit meiner Bancomatkarte kann ich überall zahlen.","en":"With my bank card I can pay everywhere.","ru":"Своей банковской картой я могу платить везде.","vi":"Tôi có thể thanh toán ở bất kỳ đâu bằng thẻ ATM của mình.","fa":"من می توانم با کارت خودپرداز خود در هر جایی پرداخت کنم."},{"de":"Ich habe meine Bancomatkarte zu Hause vergessen.","en":"I forgot my bank card at home.","ru":"Я забыл банковскую карту дома.","vi":"Tôi quên thẻ ATM ở nhà.","fa":"کارت خودپردازم را در خانه فراموش کردم."},{"de":"Die Bancomatkarte ist abgelaufen und muss erneuert werden.","en":"The bank card has expired and needs to be renewed.","ru":"Банковская карта просрочена, её надо перевыпустить.","vi":"Thẻ ATM đã hết hạn sử dụng và cần được gia hạn.","fa":"کارت ATM منقضی شده است و باید تمدید شود."}]},{"word":"die Bank","en":"bank; bench","ru":"банк; скамейка","vi":"ngân hàng","fa":"بانک","examples":[{"de":"Ich hebe Geld bei der Bank ab.","en":"I withdraw money from the bank.","ru":"Я снимаю деньги в банке.","vi":"Tôi rút tiền từ ngân hàng.","fa":"من از بانک پول برداشت می کنم."},{"de":"Wir setzen uns auf eine Bank im Park.","en":"We sit down on a bench in the park.","ru":"Мы садимся на скамейку в парке.","vi":"Chúng tôi ngồi trên một chiếc ghế dài trong công viên.","fa":"روی یک نیمکت در پارک می نشینیم."}]},{"word":"die Bankleitzahl","en":"bank sort code, routing number","ru":"банковский код (БИК)","vi":"số sắp xếp ngân hàng","fa":"شماره مرتب سازی بانک","examples":[{"de":"Für die Überweisung brauche ich Ihre Bankleitzahl.","en":"For the transfer I need your bank sort code.","ru":"Для перевода мне нужен ваш банковский код.","vi":"Tôi cần mã ngân hàng của bạn để chuyển khoản.","fa":"برای انتقال به کد بانک شما نیاز دارم."},{"de":"Die Bankleitzahl steht oben auf dem Kontoauszug.","en":"The bank sort code is at the top of the bank statement.","ru":"Банковский код указан вверху банковской выписки.","vi":"Số định tuyến ngân hàng nằm ở đầu bản sao kê tài khoản.","fa":"شماره مسیریابی بانک در بالای صورتحساب است."}]},{"word":"der Bankomat","en":"cash machine, ATM (Austrian)","ru":"банкомат (австр.)","vi":"máy ATM","fa":"دستگاه خودپرداز","examples":[{"de":"In Österreich holt man Geld vom Bankomat.","en":"In Austria you get money from the cash machine.","ru":"В Австрии деньги снимают в банкомате.","vi":"Ở Áo bạn nhận được tiền từ máy ATM.","fa":"در اتریش از دستگاه خودپرداز پول دریافت می کنید."},{"de":"Der Bankomat ist heute leider außer Betrieb.","en":"The cash machine is unfortunately out of order today.","ru":"Банкомат сегодня, к сожалению, не работает.","vi":"Rất tiếc, hôm nay máy ATM không hoạt động.","fa":"متأسفانه دستگاه خودپرداز امروز از کار افتاده است."},{"de":"Wo ist der nächste Bankomat hier in der Nähe?","en":"Where is the nearest cash machine around here?","ru":"Где здесь поблизости ближайший банкомат?","vi":"Máy ATM gần nhất ở đâu gần đây?","fa":"نزدیکترین دستگاه خودپرداز در این نزدیکی کجاست؟"}]},{"word":"die Bankomat-Karte","en":"ATM card, debit card","ru":"банковская карта","vi":"thẻ ATM","fa":"کارت خودپرداز","examples":[{"de":"Ich bezahle im Geschäft meistens mit meiner Bankomat-Karte.","en":"I usually pay in the store with my debit card.","ru":"Я обычно расплачиваюсь в магазине своей банковской картой.","vi":"Tôi thường thanh toán tại các cửa hàng bằng thẻ ATM của mình.","fa":"من معمولاً با کارت خودپرداز خود در فروشگاه ها پرداخت می کنم."},{"de":"Ich habe meine Bankomat-Karte leider verloren.","en":"I unfortunately lost my debit card.","ru":"Я, к сожалению, потерял свою банковскую карту.","vi":"Thật không may, tôi bị mất thẻ ATM.","fa":"متأسفانه کارت خودپرداز خود را گم کردم."}]},{"word":"die Bankomatkarte","en":"bank/debit card (Austrian)","ru":"банковская карта (австрийский вариант немецкого)","vi":"thẻ ATM","fa":"کارت خودپرداز","examples":[{"de":"Ich habe meine Bankomatkarte zu Hause vergessen.","en":"I have left my bank card at home.","ru":"Я забыл банковскую карту дома.","vi":"Tôi quên thẻ ATM ở nhà.","fa":"کارت خودپردازم را در خانه فراموش کردم."},{"de":"Mit der Bankomatkarte kann man am Automaten Geld abheben.","en":"With the debit card you can withdraw money at the cash machine.","ru":"Банковской картой можно снять деньги в банкомате.","vi":"Bạn có thể rút tiền từ máy ATM bằng thẻ ATM.","fa":"می توانید با استفاده از کارت خودپرداز خود از دستگاه های خودپرداز پول برداشت کنید."},{"de":"Meine Bankomatkarte wurde gestern gesperrt.","en":"My bank card was blocked yesterday.","ru":"Вчера мою банковскую карту заблокировали.","vi":"Thẻ ATM của tôi đã bị khóa ngày hôm qua.","fa":"کارت خودپرداز من دیروز مسدود شد."}]},{"word":"die Bar","en":"bar","ru":"бар","vi":"quán bar","fa":"نوار","examples":[{"de":"Am Abend gehen wir noch in eine Bar.","en":"In the evening we're going to a bar.","ru":"Вечером мы ещё пойдём в бар.","vi":"Buổi tối chúng tôi đi đến quán bar.","fa":"عصر به یک بار می رویم."},{"de":"Die Bar in unserem Hotel ist bis Mitternacht geöffnet.","en":"The bar in our hotel is open until midnight.","ru":"Бар в нашем отеле открыт до полуночи.","vi":"Quán bar trong khách sạn của chúng tôi mở cửa đến nửa đêm.","fa":"بار در هتل ما تا نیمه شب باز است."}]},{"word":"bar","en":"in cash","ru":"наличными","vi":"tiền mặt","fa":"پول نقد","examples":[{"de":"Ich bezahle lieber bar als mit Karte.","en":"I prefer to pay in cash rather than by card.","ru":"Я предпочитаю платить наличными, а не картой.","vi":"Tôi thích thanh toán bằng tiền mặt hơn là bằng thẻ.","fa":"من ترجیح می دهم نقدی پرداخت کنم تا کارت."},{"de":"Können Sie das auch bar bezahlen?","en":"Can you also pay that in cash?","ru":"Вы можете оплатить это также наличными?","vi":"Bạn cũng có thể thanh toán khoản này bằng tiền mặt không?","fa":"آیا می توانید این مبلغ را به صورت نقدی نیز پرداخت کنید؟"}]},{"word":"barfuß","en":"barefoot","ru":"босиком, босой","vi":"chân trần","fa":"پابرهنه","examples":[{"de":"Beim Yoga übt man am besten barfuß auf der Matte.","en":"In yoga it is best to practise barefoot on the mat.","ru":"Йогой лучше всего заниматься босиком на коврике.","vi":"Khi tập yoga, tốt nhất bạn nên tập chân trần trên thảm.","fa":"وقتی صحبت از یوگا می شود، بهتر است با پای برهنه روی تشک تمرین کنید."},{"de":"Sie läuft im Sommer am liebsten barfuß durch den Garten.","en":"In summer she likes most to walk barefoot through the garden.","ru":"Летом она больше всего любит ходить босиком по саду.","vi":"Cô thích đi chân trần qua vườn vào mùa hè.","fa":"او ترجیح می دهد در تابستان با پای برهنه در باغ راه برود."},{"de":"Barfuß spürst du den Boden viel deutlicher.","en":"Barefoot you feel the ground much more clearly.","ru":"Босиком ты гораздо отчётливее чувствуешь пол.","vi":"Bạn có thể cảm nhận mặt đất rõ ràng hơn nhiều khi đi chân trần.","fa":"وقتی پابرهنه هستید می توانید زمین را خیلی واضح تر احساس کنید."}]},{"word":"das Bargeld abheben","en":"to withdraw cash","ru":"снять наличные (деньги)","vi":"rút tiền mặt","fa":"پول نقد را برداشت کنید","examples":[{"de":"Ich muss noch schnell Bargeld abheben.","en":"I quickly need to withdraw some cash.","ru":"Мне нужно быстро снять наличные.","vi":"Tôi phải rút tiền mặt nhanh chóng.","fa":"باید سریع پول نقد کنم."},{"de":"Am Automaten kann man rund um die Uhr Bargeld abheben.","en":"At the machine you can withdraw cash around the clock.","ru":"В банкомате можно снять наличные круглосуточно.","vi":"Bạn có thể rút tiền mặt từ máy ATM suốt ngày đêm.","fa":"شما می توانید به صورت شبانه روزی از دستگاه های خودپرداز پول نقد برداشت کنید."},{"de":"Sie hob am Schalter Bargeld ab.","en":"She withdrew cash at the counter.","ru":"Она сняла наличные в кассе.","vi":"Cô rút tiền từ quầy.","fa":"او پول نقد را از پیشخوان برداشت."}]},{"word":"der Bart","en":"beard","ru":"борода","vi":"bộ râu","fa":"ریش","examples":[{"de":"Mein Großvater hat einen langen weißen Bart.","en":"My grandfather has a long white beard.","ru":"У моего дедушки длинная белая борода.","vi":"Ông tôi có bộ râu dài màu trắng.","fa":"پدربزرگ من ریش سفید بلندی دارد."},{"de":"Er lässt sich seit einem Jahr einen Bart wachsen.","en":"He has been growing a beard for a year.","ru":"Он отращивает бороду уже год.","vi":"Anh ấy đã nuôi râu được một năm.","fa":"او یک سال است که ریش گذاشته است."}]},{"word":"das Basilikum","en":"basil","ru":"базилик","vi":"húng quế","fa":"ریحان","examples":[{"de":"Frisches Basilikum passt hervorragend zu Tomaten.","en":"Fresh basil goes wonderfully with tomatoes.","ru":"Свежий базилик прекрасно сочетается с помидорами.","vi":"Húng quế tươi rất hợp với cà chua.","fa":"ریحان تازه با گوجه فرنگی عالی می شود."},{"de":"Für das Pesto brauchst du viel frisches Basilikum.","en":"For the pesto you need a lot of fresh basil.","ru":"Для песто тебе нужно много свежего базилика.","vi":"Bạn cần rất nhiều húng quế tươi cho món pesto.","fa":"برای پستو به مقدار زیادی ریحان تازه نیاز دارید."},{"de":"Auf dem Fensterbrett wächst ein kleiner Topf Basilikum.","en":"A small pot of basil is growing on the windowsill.","ru":"На подоконнике растёт небольшой горшочек базилика.","vi":"Một chậu húng quế nhỏ mọc trên bậu cửa sổ.","fa":"گلدان کوچکی از ریحان روی طاقچه رشد می کند."}]},{"word":"der Basketball","en":"basketball","ru":"баскетбол","vi":"bóng rổ","fa":"بسکتبال","examples":[{"de":"Die Jungen spielen nach der Schule Basketball.","en":"The boys play basketball after school.","ru":"Мальчики играют в баскетбол после школы.","vi":"Các cậu bé chơi bóng rổ sau giờ học.","fa":"پسرها بعد از مدرسه بسکتبال بازی می کنند."},{"de":"Er ist Mitglied im Basketballverein.","en":"He is a member of the basketball club.","ru":"Он состоит в баскетбольном клубе.","vi":"Anh ấy là thành viên của câu lạc bộ bóng rổ.","fa":"او عضو باشگاه بسکتبال است."}]},{"word":"basteln","en":"to do crafts","ru":"мастерить, заниматься рукоделием","vi":"thủ công","fa":"صنایع دستی","examples":[{"de":"Die Kinder basteln bunte Karten für Weihnachten.","en":"The children are making colorful cards for Christmas.","ru":"Дети мастерят разноцветные открытки на Рождество.","vi":"Các em làm những tấm thiệp đầy màu sắc đón Giáng sinh.","fa":"بچه ها برای کریسمس کارت های رنگارنگ درست می کنند."},{"de":"Am Wochenende bastle ich gern mit meinen Kindern.","en":"On weekends I like to do crafts with my children.","ru":"По выходным я люблю мастерить с детьми.","vi":"Vào cuối tuần, tôi thích làm đồ thủ công cùng các con.","fa":"در آخر هفته دوست دارم با فرزندانم کاردستی انجام دهم."}]},{"word":"die Batterie","en":"battery","ru":"батарейка, аккумулятор","vi":"pin","fa":"باتری","examples":[{"de":"Die Batterie meiner Fernbedienung ist leer.","en":"The battery of my remote control is dead.","ru":"Батарейка в моём пульте разряжена.","vi":"Pin điều khiển từ xa của tôi đã chết.","fa":"باتری ریموت کنترل من تمام شده است."},{"de":"Ich muss neue Batterien für die Taschenlampe kaufen.","en":"I need to buy new batteries for the flashlight.","ru":"Мне нужно купить новые батарейки для фонарика.","vi":"Tôi cần mua pin mới cho đèn pin.","fa":"برای چراغ قوه باید باتری نو بخرم."}]},{"word":"der Bau","en":"construction, building (site)","ru":"строительство, стройка","vi":"việc xây dựng","fa":"ساخت و ساز","examples":[{"de":"Der Bau des neuen Krankenhauses dauert zwei Jahre.","en":"The construction of the new hospital will take two years.","ru":"Строительство новой больницы займёт два года.","vi":"Việc xây dựng bệnh viện mới sẽ mất hai năm.","fa":"ساخت بیمارستان جدید دو سال به طول خواهد انجامید."},{"de":"Mein Vater arbeitet auf dem Bau.","en":"My father works in construction.","ru":"Мой отец работает в строительстве.","vi":"Bố tôi làm nghề xây dựng.","fa":"پدرم در کار ساختمانی است."},{"de":"Während des Baus war die Straße gesperrt.","en":"During the construction the road was closed.","ru":"На время строительства дорогу перекрыли.","vi":"Con đường đã bị đóng cửa trong quá trình xây dựng.","fa":"جاده در حین ساخت بسته شد."}]},{"word":"der Bauch","en":"belly, stomach","ru":"живот","vi":"dạ dày","fa":"معده","examples":[{"de":"Nach dem Essen tut mir der Bauch weh.","en":"My stomach hurts after eating.","ru":"После еды у меня болит живот.","vi":"Bụng tôi đau sau khi ăn.","fa":"معده ام بعد از خوردن غذا درد می کند."},{"de":"Er legte sich auf den Bauch.","en":"He lay down on his stomach.","ru":"Он лёг на живот.","vi":"Anh nằm sấp xuống.","fa":"روی شکم دراز کشید."}]},{"word":"bauen","en":"to build","ru":"строить","vi":"xây dựng","fa":"ساختن","examples":[{"de":"Meine Eltern bauen ein neues Haus.","en":"My parents are building a new house.","ru":"Мои родители строят новый дом.","vi":"Bố mẹ tôi đang xây một ngôi nhà mới.","fa":"پدر و مادرم در حال ساختن یک خانه جدید هستند."},{"de":"Die Stadt baut eine neue Brücke über den Fluss.","en":"The city is building a new bridge over the river.","ru":"Город строит новый мост через реку.","vi":"Thành phố đang xây dựng một cây cầu mới bắc qua sông.","fa":"شهر در حال ساخت یک پل جدید بر روی رودخانه است."}]},{"word":"der Bauer","en":"farmer","ru":"фермер, крестьянин","vi":"người nông dân","fa":"کشاورز","examples":[{"de":"Der Bauer arbeitet jeden Tag auf dem Feld.","en":"The farmer works in the field every day.","ru":"Фермер каждый день работает в поле.","vi":"Người nông dân làm việc trên cánh đồng hàng ngày.","fa":"کشاورز هر روز در مزرعه کار می کند."},{"de":"Der Bauer verkauft frisches Gemüse auf dem Markt.","en":"The farmer sells fresh vegetables at the market.","ru":"Фермер продаёт свежие овощи на рынке.","vi":"Người nông dân bán rau tươi ở chợ.","fa":"کشاورز سبزیجات تازه را در بازار می فروشد."}]},{"word":"der Bauernhof","en":"farm","ru":"крестьянский двор, ферма","vi":"trang trại","fa":"مزرعه","examples":[{"de":"Wir haben den Sommer auf einem Bauernhof verbracht.","en":"We spent the summer on a farm.","ru":"Лето мы провели на ферме.","vi":"Chúng tôi đã trải qua mùa hè ở một trang trại.","fa":"تابستان را در مزرعه گذراندیم."},{"de":"Auf dem Bauernhof leben viele Tiere.","en":"Many animals live on the farm.","ru":"На ферме живёт много животных.","vi":"Nhiều động vật sống trong trang trại.","fa":"حیوانات زیادی در مزرعه زندگی می کنند."},{"de":"Der Bauernhof liegt weit außerhalb der Stadt.","en":"The farm lies far outside the town.","ru":"Ферма расположена далеко за городом.","vi":"Trang trại ở xa thành phố.","fa":"مزرعه در خارج از شهر قرار دارد."}]},{"word":"der Baum","en":"tree","ru":"дерево","vi":"cái cây","fa":"درخت","examples":[{"de":"Im Garten steht ein großer Baum.","en":"There is a big tree in the garden.","ru":"В саду растёт большое дерево.","vi":"Có một cái cây lớn trong vườn.","fa":"یک درخت بزرگ در باغ وجود دارد."},{"de":"Im Herbst fallen die Blätter von den Bäumen.","en":"In autumn the leaves fall from the trees.","ru":"Осенью листья падают с деревьев.","vi":"Vào mùa thu, lá rụng khỏi cây.","fa":"در پاییز برگها از درختان می ریزند."}]},{"word":"beachten","en":"to pay attention to; to observe (rules)","ru":"соблюдать, обращать внимание","vi":"ghi chú","fa":"توجه داشته باشید","examples":[{"de":"Bitte beachten Sie die Verkehrsregeln.","en":"Please observe the traffic rules.","ru":"Пожалуйста, соблюдайте правила дорожного движения.","vi":"Hãy tuân thủ các quy định giao thông.","fa":"لطفا قوانین راهنمایی و رانندگی را رعایت کنید"},{"de":"Er hat die Warnung nicht beachtet.","en":"He didn't pay attention to the warning.","ru":"Он не обратил внимания на предупреждение.","vi":"Anh ta không chú ý đến lời cảnh báo.","fa":"او به هشدار توجه نکرد."}]},{"word":"der Beamte","en":"civil servant, official","ru":"чиновник, госслужащий","vi":"quan chức","fa":"رسمی","examples":[{"de":"Der Beamte prüft meine Unterlagen.","en":"The official checks my documents.","ru":"Чиновник проверяет мои документы.","vi":"Nhân viên kiểm tra giấy tờ của tôi.","fa":"افسر مدارکم را چک می کند."},{"de":"Mein Onkel ist Beamter bei der Stadtverwaltung.","en":"My uncle is a civil servant at the city administration.","ru":"Мой дядя — чиновник в городской администрации.","vi":"Chú tôi là một quan chức chính quyền thành phố.","fa":"عمویم یکی از مقامات شهرداری است."}]},{"word":"die Beamtin","en":"civil servant, official (female)","ru":"чиновница, государственная служащая (женщина)","vi":"viên chức","fa":"افسر","examples":[{"de":"Die Beamtin am Schalter war sehr freundlich.","en":"The official at the counter was very friendly.","ru":"Служащая у стойки была очень приветливой.","vi":"Nhân viên bán hàng ở quầy rất thân thiện.","fa":"کارمند پیشخوان بسیار صمیمی بود."},{"de":"Meine Tante ist Beamtin bei der Stadt.","en":"My aunt is a civil servant for the city.","ru":"Моя тётя — государственная служащая в городской администрации.","vi":"Dì tôi là nhân viên thành phố.","fa":"خاله من کارمند شهرداری است."},{"de":"Die Beamtin hat meinen Antrag sofort bearbeitet.","en":"The official processed my application straight away.","ru":"Служащая сразу же обработала мою заявку.","vi":"Viên chức xử lý đơn của tôi ngay lập tức.","fa":"افسر بلافاصله به درخواست من رسیدگی کرد."}]},{"word":"beantragen","en":"to apply for","ru":"подавать заявление (на что-л.)","vi":"áp dụng","fa":"اعمال شود","examples":[{"de":"Ich möchte ein neues Visum beantragen.","en":"I would like to apply for a new visa.","ru":"Я хочу подать заявление на новую визу.","vi":"Tôi muốn nộp đơn xin thị thực mới.","fa":"من می خواهم برای ویزای جدید اقدام کنم."},{"de":"Sie hat einen Kredit bei der Bank beantragt.","en":"She applied for a loan at the bank.","ru":"Она подала заявку на кредит в банке.","vi":"Cô đã nộp đơn xin vay tiền từ ngân hàng.","fa":"او برای دریافت وام از بانک اقدام کرد."}]},{"word":"beantworten","en":"to answer","ru":"отвечать (на что-л.)","vi":"câu trả lời","fa":"پاسخ دهید","examples":[{"de":"Können Sie meine Frage beantworten?","en":"Can you answer my question?","ru":"Вы можете ответить на мой вопрос?","vi":"Bạn có thể trả lời câu hỏi của tôi được không?","fa":"می توانید به سوال من پاسخ دهید؟"},{"de":"Der Lehrer beantwortet alle Fragen der Schüler.","en":"The teacher answers all the students' questions.","ru":"Учитель отвечает на все вопросы учеников.","vi":"Giáo viên giải đáp mọi thắc mắc của học sinh.","fa":"معلم به تمام سوالات دانش آموزان پاسخ می دهد."}]},{"word":"der Bedarf","en":"need, demand","ru":"потребность, спрос","vi":"sự cần thiết","fa":"نیاز","examples":[{"de":"Bei Bedarf können Sie mich anrufen.","en":"If needed, you can call me.","ru":"При необходимости вы можете мне позвонить.","vi":"Nếu cần thiết, bạn có thể gọi cho tôi.","fa":"در صورت لزوم می توانید با من تماس بگیرید."},{"de":"Der Bedarf an Fachkräften steigt.","en":"The demand for skilled workers is increasing.","ru":"Спрос на квалифицированных специалистов растёт.","vi":"Nhu cầu về công nhân lành nghề ngày càng tăng.","fa":"نیاز به کارگران ماهر در حال افزایش است."}]},{"word":"bedeuten","en":"to mean","ru":"означать","vi":"nghĩa là","fa":"معنی","examples":[{"de":"Was bedeutet dieses Wort?","en":"What does this word mean?","ru":"Что означает это слово?","vi":"Từ này có nghĩa là gì?","fa":"این کلمه به چه معناست؟"},{"de":"Sein Schweigen bedeutet nicht, dass er böse ist.","en":"His silence doesn't mean that he is angry.","ru":"Его молчание не означает, что он злится.","vi":"Sự im lặng của anh ấy không có nghĩa là anh ấy xấu xa.","fa":"سکوت او به معنای بد بودن او نیست."}]},{"word":"die Bedeutung","en":"meaning, significance","ru":"значение, важность","vi":"ý nghĩa","fa":"معنی","examples":[{"de":"Kennst du die Bedeutung dieses Wortes?","en":"Do you know the meaning of this word?","ru":"Ты знаешь значение этого слова?","vi":"Bạn có biết ý nghĩa của từ này không?","fa":"آیا معنی این کلمه را می دانید؟"},{"de":"Dieser Tag hat für mich eine besondere Bedeutung.","en":"This day has a special significance for me.","ru":"Этот день имеет для меня особое значение.","vi":"Ngày này có một ý nghĩa đặc biệt đối với tôi.","fa":"این روز برای من معنای خاصی دارد."},{"de":"Die Bedeutung des Klimaschutzes wächst ständig.","en":"The importance of climate protection is constantly growing.","ru":"Важность защиты климата постоянно растёт.","vi":"Tầm quan trọng của việc bảo vệ khí hậu không ngừng tăng lên.","fa":"اهمیت حفاظت از آب و هوا به طور مداوم در حال افزایش است."}]},{"word":"bedienen","en":"to serve; to operate","ru":"обслуживать","vi":"vận hành","fa":"عمل کنند","examples":[{"de":"Die Kellnerin bedient die Gäste freundlich.","en":"The waitress serves the guests kindly.","ru":"Официантка вежливо обслуживает гостей.","vi":"Cô hầu bàn phục vụ khách một cách thân thiện.","fa":"پیشخدمت به صورت دوستانه از مهمانان پذیرایی می کند."},{"de":"Kannst du diese Maschine bedienen?","en":"Can you operate this machine?","ru":"Ты умеешь пользоваться этой машиной?","vi":"Bạn có thể vận hành chiếc máy này không?","fa":"آیا می توانید با این دستگاه کار کنید؟"}]},{"word":"die Bedienungsanleitung","en":"instruction manual","ru":"инструкция по эксплуатации","vi":"hướng dẫn vận hành","fa":"دستورالعمل های عملیاتی","examples":[{"de":"Lies die Bedienungsanleitung, bevor du das Gerät benutzt.","en":"Read the instruction manual before using the device.","ru":"Прочитай инструкцию, прежде чем пользоваться прибором.","vi":"Đọc hướng dẫn sử dụng trước khi sử dụng thiết bị.","fa":"قبل از استفاده از دستگاه، دفترچه راهنما را مطالعه کنید."},{"de":"Die Bedienungsanleitung liegt dem Gerät bei.","en":"The instruction manual is included with the device.","ru":"Инструкция прилагается к прибору.","vi":"Các hướng dẫn vận hành được bao gồm trong thiết bị.","fa":"دستورالعمل های عملیاتی همراه با دستگاه است."}]},{"word":"die Bedingung","en":"condition","ru":"условие","vi":"điều kiện","fa":"شرط","examples":[{"de":"Ich akzeptiere die Bedingungen des Vertrags.","en":"I accept the conditions of the contract.","ru":"Я принимаю условия договора.","vi":"Tôi chấp nhận các điều khoản của hợp đồng.","fa":"من شرایط قرارداد را می پذیرم."},{"de":"Unter dieser Bedingung stimme ich zu.","en":"Under this condition I agree.","ru":"При этом условии я согласен.","vi":"Với điều kiện này tôi đồng ý.","fa":"به این شرط موافقم"}]},{"word":"bedrohen","en":"to threaten, to endanger","ru":"угрожать, ставить под угрозу","vi":"đe dọa","fa":"تهدید کند","examples":[{"de":"Der steigende Meeresspiegel bedroht viele Inseln.","en":"The rising sea level threatens many islands.","ru":"Повышение уровня моря угрожает многим островам.","vi":"Mực nước biển dâng cao đe dọa nhiều hòn đảo.","fa":"افزایش سطح آب دریاها بسیاری از جزایر را تهدید می کند."},{"de":"Die Erwärmung bedroht das Leben in den Ozeanen.","en":"The warming endangers life in the oceans.","ru":"Потепление угрожает жизни в океанах.","vi":"Sự nóng lên đe dọa sự sống ở các đại dương.","fa":"گرمایش زندگی در اقیانوس ها را تهدید می کند."},{"de":"Dürren bedrohen die Ernte ganzer Regionen.","en":"Droughts threaten the harvest of entire regions.","ru":"Засухи угрожают урожаю целых регионов.","vi":"Hạn hán đe dọa thu hoạch của toàn bộ khu vực.","fa":"خشکسالی برداشت کل مناطق را تهدید می کند."}]},{"word":"beeinflussen","en":"to influence","ru":"влиять","vi":"ảnh hưởng","fa":"نفوذ","examples":[{"de":"Die Werbung beeinflusst unser Kaufverhalten.","en":"Advertising influences our buying behavior.","ru":"Реклама влияет на наше покупательское поведение.","vi":"Quảng cáo ảnh hưởng đến hành vi mua hàng của chúng ta.","fa":"تبلیغات بر رفتار خرید ما تأثیر می گذارد."},{"de":"Lass dich nicht von anderen beeinflussen.","en":"Don't let yourself be influenced by others.","ru":"Не позволяй другим влиять на тебя.","vi":"Đừng để người khác ảnh hưởng đến bạn.","fa":"اجازه ندهید دیگران بر شما تأثیر بگذارند."}]},{"word":"beenden","en":"to finish, end","ru":"заканчивать","vi":"kết thúc","fa":"تمام کردن","examples":[{"de":"Ich muss meine Arbeit noch heute beenden.","en":"I have to finish my work today.","ru":"Я должен закончить свою работу сегодня.","vi":"Hôm nay tôi phải hoàn thành công việc của mình.","fa":"امروز باید کارم را تمام کنم."},{"de":"Sie beendete das Gespräch schnell.","en":"She ended the conversation quickly.","ru":"Она быстро закончила разговор.","vi":"Cô nhanh chóng kết thúc cuộc trò chuyện.","fa":"او به سرعت گفتگو را تمام کرد."}]},{"word":"befinden","en":"to be located, to find oneself","ru":"находиться, располагаться","vi":"nằm","fa":"واقع شده است","examples":[{"de":"Das Museum befindet sich im Zentrum der Stadt.","en":"The museum is located in the centre of the city.","ru":"Музей находится в центре города.","vi":"Bảo tàng nằm ở trung tâm thành phố.","fa":"این موزه در مرکز شهر قرار دارد."},{"de":"Wir befinden uns gerade auf dem Weg nach Hause.","en":"We are currently on our way home.","ru":"Мы сейчас на пути домой.","vi":"Hiện tại chúng tôi đang trên đường về nhà.","fa":"در حال حاضر در راه خانه هستیم."},{"de":"Wo befindet sich der nächste Bahnhof?","en":"Where is the nearest railway station?","ru":"Где находится ближайший вокзал?","vi":"Ga xe lửa gần nhất ở đâu?","fa":"نزدیکترین ایستگاه قطار کجاست؟"}]},{"word":"befördern","en":"to promote","ru":"повышать (по службе), продвигать","vi":"vận chuyển","fa":"حمل و نقل","examples":[{"de":"Nach zwei Jahren wurde sie zur Teamleiterin befördert.","en":"After two years she was promoted to team leader.","ru":"Через два года её повысили до руководителя команды.","vi":"Sau hai năm, cô được thăng chức trưởng nhóm.","fa":"پس از دو سال، او به عنوان رهبر تیم ارتقا یافت."},{"de":"Der Chef will mich im nächsten Jahr befördern.","en":"The boss wants to promote me next year.","ru":"Начальник хочет повысить меня в следующем году.","vi":"Sếp muốn thăng chức cho tôi vào năm tới.","fa":"رئیس می خواهد سال آینده مرا ارتقا دهد."},{"de":"Wer gute Leistung zeigt, wird hier oft schnell befördert.","en":"Anyone who performs well is often promoted quickly here.","ru":"Тех, кто хорошо работает, здесь часто быстро повышают.","vi":"Những người làm tốt thường được thăng chức nhanh chóng.","fa":"کسانی که عملکرد خوبی دارند اغلب به سرعت ارتقا می یابند."}]},{"word":"die Beförderung","en":"promotion","ru":"повышение по службе, продвижение","vi":"vận chuyển","fa":"حمل و نقل","examples":[{"de":"Nach drei Jahren bekam er endlich eine Beförderung.","en":"After three years he finally got a promotion.","ru":"Через три года он наконец получил повышение.","vi":"Sau ba năm, cuối cùng anh cũng được thăng chức.","fa":"بعد از سه سال بالاخره ترفیع گرفت."},{"de":"Mit der Beförderung steigt auch sein Gehalt.","en":"With the promotion his salary rises too.","ru":"С повышением растёт и его зарплата.","vi":"Với sự thăng tiến, lương của anh ấy cũng tăng lên.","fa":"با ارتقاء، حقوق او نیز افزایش می یابد."},{"de":"Sie hofft auf eine Beförderung zur Abteilungsleiterin.","en":"She's hoping for a promotion to head of department.","ru":"Она надеется на повышение до начальника отдела.","vi":"Cô ấy hy vọng sẽ được thăng chức lên trưởng phòng.","fa":"او امیدوار است که به ریاست بخش ارتقا یابد."}]},{"word":"befreit","en":"freed, exempt","ru":"освобождённый","vi":"được giải thoát","fa":"آزاد شد","examples":[{"de":"Er ist von der Steuer befreit.","en":"He is exempt from tax.","ru":"Он освобождён от налога.","vi":"Anh ta được miễn thuế.","fa":"او از پرداخت مالیات معاف است."},{"de":"Die Geiseln wurden endlich befreit.","en":"The hostages were finally freed.","ru":"Заложников наконец освободили.","vi":"Các con tin cuối cùng đã được giải thoát.","fa":"گروگان ها سرانجام آزاد شدند."}]},{"word":"die Befreiung","en":"liberation","ru":"освобождение","vi":"sự giải phóng","fa":"the liberation","examples":[{"de":"Die Befreiung der Stadt wird jedes Jahr gefeiert.","en":"The liberation of the city is celebrated every year.","ru":"Освобождение города празднуют каждый год.","vi":"Lễ giải phóng thành phố được tổ chức hàng năm.","fa":"جشن آزادسازی این شهر هر ساله برگزار می شود."},{"de":"Nach der Befreiung kehrten viele Geflüchtete zurück.","en":"After the liberation many refugees returned.","ru":"После освобождения многие беженцы вернулись.","vi":"Sau giải phóng, nhiều người tị nạn đã trở về.","fa":"پس از آزادی، بسیاری از پناهندگان بازگشتند."},{"de":"Die Befreiung vom Diktator dauerte Jahre.","en":"The liberation from the dictator took years.","ru":"Освобождение от диктатора заняло годы.","vi":"Việc giải phóng khỏi nhà độc tài phải mất nhiều năm.","fa":"رهایی از دست دیکتاتور سال ها طول کشید."}]},{"word":"befriedigend","en":"satisfactory","ru":"удовлетворительный","vi":"thỏa đáng","fa":"رضایت بخش","examples":[{"de":"Ihre Leistung im Test war befriedigend.","en":"Her performance in the test was satisfactory.","ru":"Её результат в тесте был удовлетворительным.","vi":"Hiệu suất của họ trong bài kiểm tra là thỏa đáng.","fa":"عملکرد آنها در آزمون رضایت بخش بود."},{"de":"Die Note 'befriedigend' entspricht einer 3.","en":"The grade 'satisfactory' corresponds to a 3.","ru":"Оценка «удовлетворительно» соответствует тройке.","vi":"Điểm 'đạt yêu cầu' tương ứng với điểm 3.","fa":"نمره \"رضایت بخش\" با 3 مطابقت دارد."}]},{"word":"befürchten","en":"to fear, to be afraid (that something bad will happen)","ru":"опасаться, бояться (что случится что-то плохое)","vi":"nỗi sợ hãi","fa":"ترس","examples":[{"de":"Ich befürchte, dass es heute regnen wird.","en":"I'm afraid it will rain today.","ru":"Боюсь, что сегодня пойдёт дождь.","vi":"Tôi sợ hôm nay trời sẽ mưa.","fa":"میترسم امروز بارون بباره"},{"de":"Wir befürchten das Schlimmste.","en":"We fear the worst.","ru":"Мы опасаемся худшего.","vi":"Chúng tôi sợ điều tồi tệ nhất.","fa":"ما از بدترین می ترسیم"},{"de":"Sie befürchtete, den Zug zu verpassen.","en":"She was afraid of missing the train.","ru":"Она боялась опоздать на поезд.","vi":"Cô sợ lỡ chuyến tàu.","fa":"می ترسید قطار را از دست بدهد."}]},{"word":"begabt","en":"gifted; talented","ru":"одарённый, способный","vi":"có năng khiếu","fa":"با استعداد","examples":[{"de":"Die Begabte bekam ein Stipendium.","en":"The gifted one received a scholarship.","ru":"Одарённый получил стипендию.","vi":"Người tài năng nhận được học bổng.","fa":"فرد مستعد بورسیه تحصیلی دریافت کرد."},{"de":"Sie ist eine musikalisch sehr begabte Schülerin.","en":"She is a very musically gifted pupil.","ru":"Она очень музыкально одарённая ученица.","vi":"Cô ấy là một sinh viên rất tài năng về âm nhạc.","fa":"او از نظر موسیقی دانش آموز بسیار با استعدادی است."},{"de":"Der junge Maler gilt als außergewöhnlich begabt.","en":"The young painter is regarded as exceptionally talented.","ru":"Молодого художника считают исключительно талантливым.","vi":"Họa sĩ trẻ được đánh giá là có tài năng đặc biệt.","fa":"این نقاش جوان را استعداد فوق العاده ای می دانند."}]},{"word":"begegnen","en":"to meet, encounter","ru":"встречать(ся)","vi":"gặp phải","fa":"برخورد","examples":[{"de":"Ich bin ihr gestern im Park begegnet.","en":"I met her yesterday in the park.","ru":"Я встретил её вчера в парке.","vi":"Hôm qua tôi gặp cô ấy ở công viên.","fa":"دیروز در پارک با او آشنا شدم."},{"de":"Auf der Reise begegneten wir vielen interessanten Menschen.","en":"On the trip we met many interesting people.","ru":"В путешествии мы встретили много интересных людей.","vi":"Trong chuyến đi chúng tôi đã gặp nhiều người thú vị.","fa":"در سفر با افراد جالب زیادی آشنا شدیم."}]},{"word":"die Begegnung","en":"encounter, meeting","ru":"встреча, знакомство","vi":"cuộc gặp gỡ","fa":"برخورد","examples":[{"de":"Die Begegnung mit ihm hat mich verändert.","en":"The encounter with him changed me.","ru":"Встреча с ним изменила меня.","vi":"Gặp anh đã thay đổi tôi.","fa":"ملاقات با او مرا تغییر داد."},{"de":"Auf Reisen kommt es zu vielen interessanten Begegnungen.","en":"When travelling you have many interesting encounters.","ru":"В путешествиях случается много интересных встреч.","vi":"Nhiều cuộc gặp gỡ thú vị xảy ra khi đi du lịch.","fa":"بسیاری از برخوردهای جالب در سفر رخ می دهد."},{"de":"Es war eine zufällige Begegnung auf der Straße.","en":"It was a chance encounter on the street.","ru":"Это была случайная встреча на улице.","vi":"Đó là một cuộc gặp gỡ tình cờ trên đường phố.","fa":"این یک ملاقات تصادفی در خیابان بود."}]},{"word":"begeistert","en":"enthusiastic","ru":"воодушевлённый, в восторге","vi":"hồi hộp","fa":"هیجان زده","examples":[{"de":"Die Kinder waren begeistert von dem Zirkus.","en":"The children were thrilled with the circus.","ru":"Дети были в восторге от цирка.","vi":"Trẻ em rất hào hứng với buổi xiếc.","fa":"بچه ها مشتاق سیرک بودند."},{"de":"Er ist begeistert von seinem neuen Job.","en":"He is enthusiastic about his new job.","ru":"Он в восторге от своей новой работы.","vi":"Anh ấy rất hào hứng với công việc mới của mình.","fa":"او در مورد شغل جدید خود هیجان زده است."}]},{"word":"die Begeisterung","en":"enthusiasm","ru":"воодушевление; восторг","vi":"sự nhiệt tình","fa":"شور و شوق","examples":[{"de":"Die Kinder spielten mit großer Begeisterung.","en":"The children played with great enthusiasm.","ru":"Дети играли с большим воодушевлением.","vi":"Các em chơi rất nhiệt tình.","fa":"بچه ها با اشتیاق زیاد بازی می کردند."},{"de":"Seine Rede löste Begeisterung beim Publikum aus.","en":"His speech sparked enthusiasm in the audience.","ru":"Его речь вызвала восторг у публики.","vi":"Bài phát biểu của ông đã khơi dậy sự nhiệt tình trong khán giả.","fa":"سخنان او شور و شوق حاضران را برانگیخت."}]},{"word":"der Beginn","en":"beginning, start","ru":"начало","vi":"sự khởi đầu","fa":"آغاز","examples":[{"de":"Der Beginn des Films ist um acht Uhr.","en":"The start of the film is at eight o'clock.","ru":"Начало фильма в восемь часов.","vi":"Bộ phim bắt đầu lúc tám giờ.","fa":"فیلم ساعت هشت شروع می شود."},{"de":"Gleich zu Beginn gab es ein kleines Problem.","en":"Right at the beginning there was a small problem.","ru":"В самом начале была небольшая проблема.","vi":"Có một vấn đề nhỏ ngay từ đầu.","fa":"در همان ابتدا یک مشکل کوچک وجود داشت."},{"de":"Der Beginn der Reise war sehr aufregend.","en":"The beginning of the journey was very exciting.","ru":"Начало путешествия было очень волнующим.","vi":"Sự khởi đầu của cuộc hành trình rất thú vị.","fa":"شروع سفر بسیار هیجان انگیز بود."}]},{"word":"beginnen","en":"to begin","ru":"начинать(ся)","vi":"bắt đầu","fa":"آغاز شود","examples":[{"de":"Der Unterricht beginnt um acht Uhr.","en":"Class begins at eight o'clock.","ru":"Урок начинается в восемь часов.","vi":"Lớp học bắt đầu lúc tám giờ.","fa":"شروع کلاس ها ساعت هشت."},{"de":"Wir beginnen morgen mit dem neuen Projekt.","en":"We are starting the new project tomorrow.","ru":"Мы начинаем новый проект завтра.","vi":"Chúng tôi bắt đầu dự án mới vào ngày mai.","fa":"پروژه جدید را از فردا شروع می کنیم."}]},{"word":"beglaubigt","en":"certified, authenticated","ru":"заверенный, нотариально удостоверенный","vi":"được chứng nhận","fa":"گواهی شده است","examples":[{"de":"Für die Bewerbung brauche ich eine beglaubigte Kopie.","en":"For the application I need a certified copy.","ru":"Для заявления мне нужна заверенная копия.","vi":"Tôi cần một bản sao có chứng thực để nộp đơn.","fa":"برای درخواست به یک کپی تایید شده نیاز دارم."},{"de":"Die Übersetzung muss beglaubigt sein.","en":"The translation must be certified.","ru":"Перевод должен быть заверен.","vi":"Bản dịch phải được chứng thực.","fa":"ترجمه باید تایید شده باشد."},{"de":"Er legte ein beglaubigtes Zeugnis vor.","en":"He presented a certified certificate.","ru":"Он предъявил заверенное свидетельство.","vi":"Ông đã trình bày một giấy chứng nhận được chứng nhận.","fa":"وی گواهی تایید شده ارائه کرد."}]},{"word":"die Beglaubigung","en":"certification, authentication (of a document)","ru":"заверение, нотариальное удостоверение (документа)","vi":"chứng nhận","fa":"گواهینامه","examples":[{"de":"Für den Antrag brauche ich eine Beglaubigung meines Zeugnisses.","en":"For the application I need a certification of my certificate.","ru":"Для заявления мне нужно заверение моего свидетельства.","vi":"Đối với đơn đăng ký, tôi cần chứng chỉ của mình để được chứng nhận.","fa":"برای درخواست من به گواهینامه نیاز دارم تا گواهی شود."},{"de":"Die Beglaubigung kostet beim Amt fünf Euro.","en":"The certification costs five euros at the office.","ru":"Заверение стоит пять евро в учреждении.","vi":"Giấy chứng nhận có giá năm euro tại văn phòng.","fa":"هزینه صدور گواهینامه در دفتر پنج یورو است."},{"de":"Ohne Beglaubigung wird die Kopie nicht akzeptiert.","en":"Without certification the copy will not be accepted.","ru":"Без заверения копию не примут.","vi":"Bản sao sẽ không được chấp nhận nếu không có chứng nhận.","fa":"کپی بدون گواهی پذیرفته نمی شود."}]},{"word":"begleiten","en":"to accompany","ru":"сопровождать","vi":"đi cùng","fa":"همراهی کنند","examples":[{"de":"Kannst du mich zum Arzt begleiten?","en":"Can you accompany me to the doctor?","ru":"Ты можешь сопроводить меня к врачу?","vi":"Bạn có thể đi cùng tôi tới gặp bác sĩ được không?","fa":"می توانید من را تا دکتر همراهی کنید؟"},{"de":"Der Vater begleitete seine Tochter zur Schule.","en":"The father accompanied his daughter to school.","ru":"Отец проводил дочь до школы.","vi":"Người cha đi cùng con gái tới trường.","fa":"پدر دخترش را تا مدرسه همراهی کرد."}]},{"word":"begrenzt","en":"limited","ru":"ограниченный","vi":"hạn chế","fa":"محدود است","examples":[{"de":"Die Anzahl der Plätze ist begrenzt.","en":"The number of seats is limited.","ru":"Количество мест ограничено.","vi":"Số lượng chỗ có hạn.","fa":"تعداد مکان ها محدود است."},{"de":"Wir haben nur begrenzte Zeit.","en":"We only have limited time.","ru":"У нас только ограниченное время.","vi":"Chúng tôi chỉ có thời gian hạn chế.","fa":"ما فقط زمان محدودی داریم."}]},{"word":"begründen","en":"to justify, give reasons for","ru":"обосновывать","vi":"biện minh","fa":"توجیه کند","examples":[{"de":"Sie musste ihre Entscheidung begründen.","en":"She had to justify her decision.","ru":"Ей пришлось обосновать своё решение.","vi":"Cô phải biện minh cho quyết định của mình.","fa":"او باید تصمیم خود را توجیه می کرد."},{"de":"Er konnte seine Meinung nicht gut begründen.","en":"He couldn't justify his opinion well.","ru":"Он не смог хорошо обосновать своё мнение.","vi":"Anh ấy không thể biện minh tốt cho ý kiến ​​​​của mình.","fa":"او نمی توانست نظر خود را به خوبی توجیه کند."}]},{"word":"die Begründung","en":"reason, justification","ru":"обоснование, объяснение (причины)","vi":"sự biện minh","fa":"توجیه","examples":[{"de":"Der Lehrer verlangte eine Begründung für die Fehlzeit.","en":"The teacher demanded a reason for the absence.","ru":"Учитель потребовал объяснения причины отсутствия.","vi":"Giáo viên yêu cầu một lời giải thích cho sự vắng mặt.","fa":"معلم برای غیبت توضیح خواست."},{"de":"Die Absage kam ohne jede Begründung.","en":"The rejection came without any explanation.","ru":"Отказ пришёл безо всякого обоснования.","vi":"Việc hủy bỏ đến mà không có bất kỳ lời giải thích.","fa":"لغو بدون هیچ توضیحی انجام شد."},{"de":"Bitte geben Sie eine kurze Begründung an.","en":"Please provide a brief justification.","ru":"Приведите, пожалуйста, краткое обоснование.","vi":"Vui lòng cung cấp một lời biện minh ngắn gọn.","fa":"لطفا یک توضیح مختصر ارائه دهید."}]},{"word":"begrüßen","en":"to greet, welcome","ru":"приветствовать","vi":"chào mừng","fa":"خوش آمدید","examples":[{"de":"Der Gastgeber begrüßte alle Gäste herzlich.","en":"The host warmly welcomed all the guests.","ru":"Хозяин сердечно приветствовал всех гостей.","vi":"Chủ nhà nồng nhiệt chào đón tất cả các vị khách.","fa":"میزبان به گرمی از همه مهمانان استقبال کرد."},{"de":"Ich begrüße meine Kollegen jeden Morgen.","en":"I greet my colleagues every morning.","ru":"Я приветствую своих коллег каждое утро.","vi":"Tôi chào đồng nghiệp của mình vào mỗi buổi sáng.","fa":"من هر روز صبح به همکارانم سلام می کنم."}]},{"word":"behalten","en":"to keep","ru":"оставлять, сохранять, держать","vi":"giữ","fa":"نگه دارید","examples":[{"de":"Du kannst das Buch behalten.","en":"You can keep the book.","ru":"Ты можешь оставить эту книгу себе.","vi":"Bạn có thể giữ cuốn sách.","fa":"می توانید کتاب را نگه دارید."},{"de":"Ich kann mir seinen Namen einfach nicht behalten.","en":"I just can't remember his name.","ru":"Я просто не могу запомнить его имя.","vi":"Tôi chỉ không thể nhớ tên anh ấy.","fa":"فقط اسمشو یادم نمیاد"}]},{"word":"der Behälter","en":"container","ru":"ёмкость, контейнер, сосуд","vi":"thùng chứa","fa":"ظرف","examples":[{"de":"Füll die Suppe bitte in diesen Behälter.","en":"Please pour the soup into this container.","ru":"Перелейте, пожалуйста, суп в эту ёмкость.","vi":"Hãy đổ súp vào thùng này.","fa":"لطفا سوپ را در این ظرف پر کنید."},{"de":"Der Behälter ist leider nicht ganz dicht.","en":"Unfortunately the container is not quite leakproof.","ru":"К сожалению, контейнер не совсем герметичен.","vi":"Thật không may, thùng chứa không hoàn toàn kín.","fa":"متأسفانه ظرف کاملاً سفت نیست."},{"de":"Wir lagern das Mehl in einem großen Behälter.","en":"We store the flour in a large container.","ru":"Мы храним муку в большой ёмкости.","vi":"Chúng tôi bảo quản bột mì trong một thùng chứa lớn.","fa":"آرد را در ظرف بزرگی نگهداری می کنیم."}]},{"word":"behandeln","en":"to treat","ru":"лечить, обращаться (с кем-л.)","vi":"đối xử","fa":"درمان","examples":[{"de":"Der Arzt behandelt den Patienten mit Antibiotika.","en":"The doctor treats the patient with antibiotics.","ru":"Врач лечит пациента антибиотиками.","vi":"Bác sĩ điều trị cho bệnh nhân bằng kháng sinh.","fa":"پزشک بیمار را با آنتی بیوتیک درمان می کند."},{"de":"Man sollte alle Menschen fair behandeln.","en":"One should treat all people fairly.","ru":"Со всеми людьми нужно обращаться справедливо.","vi":"Mọi người nên được đối xử công bằng.","fa":"باید با همه منصفانه رفتار شود."}]},{"word":"die Behandlung","en":"treatment","ru":"лечение","vi":"việc điều trị","fa":"درمان","examples":[{"de":"Die Behandlung beim Zahnarzt tat gar nicht weh.","en":"The treatment at the dentist didn't hurt at all.","ru":"Лечение у стоматолога совсем не было болезненным.","vi":"Việc điều trị nha khoa không gây đau đớn gì cả.","fa":"درمان دندانپزشکی اصلاً ضرری نداشت."},{"de":"Ohne Behandlung wird die Krankheit schlimmer.","en":"Without treatment the illness gets worse.","ru":"Без лечения болезнь усугубляется.","vi":"Nếu không điều trị, bệnh sẽ nặng hơn.","fa":"بدون درمان، بیماری بدتر می شود."}]},{"word":"behaupten","en":"to claim, assert","ru":"утверждать","vi":"yêu sách","fa":"ادعا","examples":[{"de":"Er behauptet, dass er unschuldig ist.","en":"He claims that he is innocent.","ru":"Он утверждает, что он невиновен.","vi":"Anh ta khẳng định mình vô tội.","fa":"او ادعا می کند که بی گناه است."},{"de":"Sie behauptet immer, recht zu haben.","en":"She always claims to be right.","ru":"Она всегда утверждает, что права.","vi":"Cô ấy luôn khẳng định mình đúng.","fa":"او همیشه ادعا می کند که حق دارد."}]},{"word":"behindern","en":"to hinder, obstruct","ru":"мешать, препятствовать","vi":"cản trở","fa":"مانع شود","examples":[{"de":"Der Unfall behindert den Verkehr auf der Autobahn.","en":"The accident is obstructing traffic on the highway.","ru":"Авария затрудняет движение на автомагистрали.","vi":"Vụ tai nạn khiến giao thông trên đường bị gián đoạn.","fa":"این تصادف باعث اختلال در تردد در بزرگراه می شود."},{"de":"Bitte behindere mich nicht bei der Arbeit.","en":"Please don't hinder me at work.","ru":"Пожалуйста, не мешай мне работать.","vi":"Xin đừng can thiệp vào công việc của tôi.","fa":"لطفا در کار من دخالت نکنید"}]},{"word":"die Behörde","en":"authority, agency","ru":"ведомство, учреждение","vi":"cơ quan có thẩm quyền","fa":"اقتدار","examples":[{"de":"Ich muss zur Behörde, um meinen Pass zu verlängern.","en":"I have to go to the authority to renew my passport.","ru":"Мне нужно в учреждение, чтобы продлить паспорт.","vi":"Tôi phải đến cơ quan có thẩm quyền để gia hạn hộ chiếu.","fa":"برای تمدید گذرنامه باید به مقامات مراجعه کنم."},{"de":"Die Behörden haben neue Regeln erlassen.","en":"The authorities have issued new rules.","ru":"Власти издали новые правила.","vi":"Cơ quan chức năng đã ban hành các quy định mới.","fa":"مقامات قوانین جدیدی وضع کرده اند."}]},{"word":"bei","en":"at, with, near","ru":"у, при, во время","vi":"tại","fa":"در","examples":[{"de":"Ich wohne bei meinen Eltern.","en":"I live with my parents.","ru":"Я живу у родителей.","vi":"Tôi sống với bố mẹ tôi.","fa":"من با پدر و مادرم زندگی می کنم."},{"de":"Bei Regen bleiben wir zu Hause.","en":"In case of rain, we stay at home.","ru":"В случае дождя мы останемся дома.","vi":"Nếu trời mưa thì chúng ta ở nhà.","fa":"اگر باران ببارد در خانه می مانیم."}]},{"word":"Bei uns ist es üblich, dass …","en":"Where I'm from it's common that … (customs)","ru":"У нас принято, что … (обычаи)","vi":"Tôi đến từ đâu, điều đó là bình thường…","fa":"جایی که من از آنجا هستم رایج است که…","examples":[{"de":"Bei uns ist es üblich, dass man Gäste zum Essen einlädt.","en":"Where I'm from it's common to invite guests for a meal.","ru":"У нас принято приглашать гостей на обед.","vi":"Theo thông lệ, chúng tôi mời khách đến ăn tối.","fa":"رسم بر این است که مهمانان را به شام ​​دعوت می کنیم."}]},{"word":"beid-","en":"both","ru":"оба, обе","vi":"cả hai-","fa":"هر دو-","examples":[{"de":"Beide Kinder gehen in dieselbe Schule.","en":"Both children go to the same school.","ru":"Оба ребёнка ходят в одну школу.","vi":"Cả hai đứa trẻ đều học cùng trường.","fa":"هر دو بچه به یک مدرسه می روند."},{"de":"Ich habe beide Bücher gelesen.","en":"I have read both books.","ru":"Я прочитал обе книги.","vi":"Tôi đã đọc cả hai cuốn sách.","fa":"من هر دو کتاب را خوانده ام."}]},{"word":"die Beifahrertür","en":"passenger door (of a car)","ru":"дверь переднего пассажира (в автомобиле)","vi":"cửa hành khách","fa":"درب مسافر","examples":[{"de":"Die Beifahrertür lässt sich nicht mehr richtig schließen.","en":"The passenger door no longer closes properly.","ru":"Дверь переднего пассажира больше не закрывается как следует.","vi":"Cửa hành khách không thể đóng được nữa.","fa":"درب سرنشین دیگر نمی تواند به درستی بسته شود."},{"de":"Steig bitte über die Beifahrertür ein.","en":"Please get in through the passenger door.","ru":"Садитесь, пожалуйста, через переднюю пассажирскую дверь.","vi":"Vui lòng vào bằng cửa hành khách.","fa":"لطفا از درب مسافر وارد شوید."},{"de":"Die Beifahrertür wurde bei dem Unfall beschädigt.","en":"The passenger door was damaged in the accident.","ru":"Пассажирскую дверь повредило в аварии.","vi":"Cửa hành khách bị hư hỏng trong vụ tai nạn.","fa":"در این حادثه درب سرنشین آسیب دیده است."}]},{"word":"die Beilage","en":"side dish","ru":"гарнир","vi":"phần bổ sung","fa":"مکمل","examples":[{"de":"Als Beilage gibt es Reis oder Kartoffeln.","en":"As a side dish there is rice or potatoes.","ru":"На гарнир есть рис или картофель.","vi":"Có cơm hoặc khoai tây làm món ăn phụ.","fa":"به عنوان غذای جانبی برنج یا سیب زمینی وجود دارد."},{"de":"Ein frischer Salat passt gut als Beilage zum Fisch.","en":"A fresh salad goes well as a side dish with the fish.","ru":"Свежий салат хорошо подходит как гарнир к рыбе.","vi":"Món salad tươi có thể dùng làm món ăn kèm với cá.","fa":"یک سالاد تازه به عنوان یک غذای جانبی با ماهی مناسب است."},{"de":"Welche Beilage möchten Sie zum Fleisch?","en":"Which side dish would you like with the meat?","ru":"Какой гарнир вы хотите к мясу?","vi":"Bạn muốn món ăn kèm nào với thịt?","fa":"چه غذای جانبی با گوشت میل دارید؟"}]},{"word":"das Bein","en":"leg","ru":"нога","vi":"cái chân","fa":"پا","examples":[{"de":"Er hat sich beim Skifahren das Bein gebrochen.","en":"He broke his leg while skiing.","ru":"Он сломал ногу, катаясь на лыжах.","vi":"Anh ấy bị gãy chân khi trượt tuyết.","fa":"هنگام اسکی پایش شکست."},{"de":"Der Tisch hat vier Beine.","en":"The table has four legs.","ru":"У стола четыре ножки.","vi":"Bàn có bốn chân.","fa":"میز چهار پایه دارد."}]},{"word":"beinah","en":"almost, nearly","ru":"почти, чуть не","vi":"gần như","fa":"تقریبا","examples":[{"de":"Ich hätte beinah den Bus verpasst.","en":"I almost missed the bus.","ru":"Я чуть не опоздал на автобус.","vi":"Tôi gần như đã lỡ chuyến xe buýt.","fa":"تقریباً اتوبوس را از دست دادم."},{"de":"Es ist beinah Mitternacht.","en":"It's almost midnight.","ru":"Почти полночь.","vi":"Đã gần nửa đêm rồi.","fa":"نزدیک نیمه شب است."},{"de":"Sie wäre beinah gestürzt.","en":"She nearly fell.","ru":"Она чуть не упала.","vi":"Cô gần như ngã.","fa":"او تقریباً سقوط کرد."}]},{"word":"beinahe","en":"almost","ru":"почти","vi":"gần như","fa":"تقریبا","examples":[{"de":"Ich wäre beinahe zu spät gekommen.","en":"I almost came too late.","ru":"Я чуть было не опоздал.","vi":"Tôi gần như đã muộn.","fa":"تقریبا دیر رسیدم."},{"de":"Das Glas wäre beinahe zerbrochen.","en":"The glass almost broke.","ru":"Стакан чуть не разбился.","vi":"Kính gần như vỡ.","fa":"شیشه تقریبا شکست."}]},{"word":"die Beine in die Hand nehmen","en":"to run as fast as one can / hurry","ru":"бежать со всех ног, поторопиться","vi":"chạy nhanh nhất có thể/nhanh lên","fa":"به سرعت دویدن / عجله کردن","examples":[{"de":"Nimm die Beine in die Hand, der Zug fährt gleich!","en":"Run as fast as you can, the train is about to leave!","ru":"Беги со всех ног, поезд вот-вот отправится!","vi":"Hãy nắm chặt đôi chân của bạn, tàu sắp rời đi!","fa":"پاهایت را در دست بگیر، قطار در شرف حرکت است!"}]},{"word":"das Beispiel","en":"example","ru":"пример","vi":"ví dụ","fa":"مثال","examples":[{"de":"Kannst du mir ein Beispiel geben?","en":"Can you give me an example?","ru":"Можешь привести мне пример?","vi":"Bạn có thể cho tôi một ví dụ không?","fa":"میشه مثال بزنی؟"},{"de":"Zum Beispiel könnten wir am Wochenende wandern gehen.","en":"For example, we could go hiking at the weekend.","ru":"Например, мы могли бы пойти в поход на выходных.","vi":"Ví dụ, chúng ta có thể đi leo núi vào cuối tuần.","fa":"به عنوان مثال، ما می توانیم در تعطیلات آخر هفته به پیاده روی برویم."}]},{"word":"beißen","en":"to bite","ru":"кусать","vi":"cắn","fa":"گاز گرفتن","examples":[{"de":"Der Hund hat mich in den Arm gebissen.","en":"The dog bit me in the arm.","ru":"Собака укусила меня за руку.","vi":"Con chó cắn vào tay tôi.","fa":"سگ دستم را گاز گرفت."},{"de":"Pass auf, die Mücken beißen hier stark.","en":"Watch out, the mosquitoes bite hard here.","ru":"Осторожно, здесь сильно кусаются комары.","vi":"Hãy cẩn thận, muỗi cắn rất mạnh ở đây.","fa":"مراقب باشید، پشه‌ها اینجا به شدت نیش می‌زنند."}]},{"word":"der Beitrag","en":"contribution, fee","ru":"взнос, вклад","vi":"sự đóng góp","fa":"سهم","examples":[{"de":"Jedes Mitglied zahlt einen monatlichen Beitrag.","en":"Every member pays a monthly fee.","ru":"Каждый участник платит ежемесячный взнос.","vi":"Mỗi thành viên phải trả một khoản phí hàng tháng.","fa":"هر یک از اعضا هزینه ماهانه پرداخت می کند."},{"de":"Sie hat einen wichtigen Beitrag zum Projekt geleistet.","en":"She made an important contribution to the project.","ru":"Она внесла важный вклад в проект.","vi":"Cô ấy đã có đóng góp quan trọng cho dự án.","fa":"او سهم مهمی در این پروژه داشت."}]},{"word":"bekannt","en":"known, famous","ru":"известный","vi":"được biết đến","fa":"شناخته شده است","examples":[{"de":"Dieser Sänger ist in ganz Europa bekannt.","en":"This singer is known throughout Europe.","ru":"Этот певец известен по всей Европе.","vi":"Ca sĩ này được biết đến khắp châu Âu.","fa":"این خواننده در سراسر اروپا شناخته شده است."},{"de":"Sie ist eine bekannte Schriftstellerin.","en":"She is a well-known writer.","ru":"Она известная писательница.","vi":"Cô ấy là một nhà văn nổi tiếng.","fa":"او نویسنده ای سرشناس است."}]},{"word":"bekannt geben","en":"to announce, to make public","ru":"объявлять, сообщать (публично)","vi":"thông báo","fa":"اعلام کند","examples":[{"de":"Die Firma gibt morgen die neuen Zahlen bekannt.","en":"The company will announce the new figures tomorrow.","ru":"Компания завтра объявит новые цифры.","vi":"Công ty sẽ công bố số liệu mới vào ngày mai.","fa":"این شرکت فردا ارقام جدید را اعلام خواهد کرد."},{"de":"Der Gewinner wird am Abend bekannt gegeben.","en":"The winner will be announced in the evening.","ru":"Победителя объявят вечером.","vi":"Người chiến thắng sẽ được công bố vào buổi tối.","fa":"برنده عصر اعلام می شود."},{"de":"Sie gaben ihre Verlobung offiziell bekannt.","en":"They officially announced their engagement.","ru":"Они официально объявили о помолвке.","vi":"Họ chính thức tuyên bố đính hôn.","fa":"آنها رسما نامزدی خود را اعلام کردند."}]},{"word":"bekanntgeben","en":"to announce, to make public","ru":"объявлять, сообщать (публично)","vi":"thông báo","fa":"اعلام کند","examples":[{"de":"Der Verein wird die Termine rechtzeitig bekanntgeben.","en":"The club will announce the dates in good time.","ru":"Клуб вовремя объявит даты.","vi":"Câu lạc bộ sẽ thông báo ngày vào thời điểm thích hợp.","fa":"باشگاه به موقع تاریخ ها را اعلام خواهد کرد."},{"de":"Das Ministerium gab die Entscheidung bekannt.","en":"The ministry announced the decision.","ru":"Министерство объявило о решении.","vi":"Bộ công bố quyết định.","fa":"این وزارتخانه این تصمیم را اعلام کرد."},{"de":"Wir möchten Ihnen unsere Pläne bekanntgeben.","en":"We would like to announce our plans to you.","ru":"Мы хотели бы сообщить вам о наших планах.","vi":"Chúng tôi muốn chia sẻ kế hoạch của chúng tôi với bạn.","fa":"مایلیم برنامه های خود را با شما در میان بگذاریم."}]},{"word":"bekommen","en":"to get, receive","ru":"получать","vi":"nhận được","fa":"دریافت کنید","examples":[{"de":"Ich habe gestern einen Brief bekommen.","en":"I received a letter yesterday.","ru":"Я вчера получил письмо.","vi":"Tôi đã nhận được một lá thư ngày hôm qua.","fa":"دیروز نامه ای دریافت کردم."},{"de":"Er bekommt jeden Monat sein Gehalt pünktlich.","en":"He receives his salary on time every month.","ru":"Он получает зарплату вовремя каждый месяц.","vi":"Anh ấy nhận lương đúng hạn hàng tháng.","fa":"او هر ماه حقوقش را به موقع می گیرد."}]},{"word":"belastbar","en":"resilient, able to handle pressure; able to bear loads","ru":"стрессоустойчивый, выносливый; способный выдерживать нагрузки","vi":"kiên cường","fa":"انعطاف پذیر","examples":[{"de":"Für diesen Job muss man sehr belastbar sein.","en":"For this job you have to be very resilient.","ru":"Для этой работы нужно быть очень стрессоустойчивым.","vi":"Đối với công việc này bạn phải rất kiên cường.","fa":"برای این کار باید بسیار مقاوم باشید."},{"de":"Sie ist körperlich und seelisch belastbar.","en":"She is physically and emotionally resilient.","ru":"Она вынослива физически и эмоционально.","vi":"Cô ấy kiên cường về thể chất và tinh thần.","fa":"او از نظر جسمی و روحی مقاوم است."},{"de":"Die Brücke ist bis zu 40 Tonnen belastbar.","en":"The bridge can bear up to 40 tonnes.","ru":"Мост может выдерживать до 40 тонн.","vi":"Cây cầu có thể chịu được tới 40 tấn.","fa":"ظرفیت این پل تا 40 تن است."}]},{"word":"belasten","en":"to burden, to put a strain on","ru":"нагружать, создавать нагрузку, обременять","vi":"gánh nặng","fa":"بار","examples":[{"de":"Abgase belasten die Umwelt stark.","en":"Exhaust fumes put a heavy strain on the environment.","ru":"Выхлопные газы сильно нагружают окружающую среду.","vi":"Khí thải có tác động nghiêm trọng đến môi trường.","fa":"گازهای خروجی اگزوز اثرات شدیدی بر محیط زیست دارند."},{"de":"Der viele Müll belastet die Natur.","en":"The large amount of rubbish burdens nature.","ru":"Большое количество мусора обременяет природу.","vi":"Lượng rác thải gây căng thẳng cho thiên nhiên.","fa":"حجم زباله به طبیعت فشار وارد می کند."},{"de":"Flugreisen belasten das Klima besonders.","en":"Air travel is particularly harmful to the climate.","ru":"Авиаперелёты особенно сильно нагружают климат.","vi":"Du lịch hàng không đặc biệt có hại cho khí hậu.","fa":"سفرهای هوایی به ویژه برای آب و هوا مضر است."}]},{"word":"der Beleg","en":"receipt, proof","ru":"квитанция, доказательство","vi":"biên nhận","fa":"رسید","examples":[{"de":"Bitte heben Sie den Beleg für den Kauf auf.","en":"Please keep the receipt for the purchase.","ru":"Пожалуйста, сохраните чек о покупке.","vi":"Vui lòng giữ lại bằng chứng mua hàng.","fa":"لطفا مدرک خرید را نگه دارید."},{"de":"Ohne Beleg kann ich das Geld nicht zurückerstatten.","en":"Without a receipt I cannot refund the money.","ru":"Без чека я не могу вернуть деньги.","vi":"Nếu không có biên lai tôi không thể hoàn lại tiền.","fa":"بدون رسید نمی توانم پول را پس بدهم."}]},{"word":"beleidigen","en":"to insult","ru":"оскорблять","vi":"xúc phạm","fa":"توهین","examples":[{"de":"Er hat mich mit seinen Worten beleidigt.","en":"He insulted me with his words.","ru":"Он оскорбил меня своими словами.","vi":"Anh ta xúc phạm tôi bằng lời nói của mình.","fa":"با حرفش به من توهین کرد."},{"de":"Man sollte niemanden beleidigen, auch wenn man wütend ist.","en":"One shouldn't insult anyone, even when angry.","ru":"Не стоит никого оскорблять, даже если ты злишься.","vi":"Bạn không nên xúc phạm bất cứ ai, ngay cả khi bạn đang tức giận.","fa":"شما نباید به کسی توهین کنید، حتی اگر عصبانی هستید."}]},{"word":"beliebt","en":"popular","ru":"популярный","vi":"phổ biến","fa":"محبوب","examples":[{"de":"Dieses Restaurant ist bei Touristen sehr beliebt.","en":"This restaurant is very popular with tourists.","ru":"Этот ресторан очень популярен среди туристов.","vi":"Nhà hàng này rất nổi tiếng với khách du lịch.","fa":"این رستوران در بین گردشگران بسیار محبوب است."},{"de":"Sie ist eine beliebte Lehrerin an unserer Schule.","en":"She is a popular teacher at our school.","ru":"Она популярная учительница в нашей школе.","vi":"Cô ấy là một giáo viên nổi tiếng ở trường chúng tôi.","fa":"او یک معلم محبوب در مدرسه ما است."}]},{"word":"die Belohnung","en":"reward","ru":"награда, вознаграждение","vi":"phần thưởng","fa":"پاداش","examples":[{"de":"Als Belohnung gab es ein Stück Kuchen.","en":"As a reward there was a piece of cake.","ru":"В награду был кусок пирога.","vi":"Phần thưởng là một miếng bánh.","fa":"به عنوان جایزه یک تکه کیک بود."},{"de":"Harte Arbeit verdient eine Belohnung.","en":"Hard work deserves a reward.","ru":"Тяжёлый труд заслуживает награды.","vi":"Làm việc chăm chỉ xứng đáng được khen thưởng.","fa":"سخت کوشی مستحق پاداش است."},{"de":"Die Belohnung war höher als erwartet.","en":"The reward was higher than expected.","ru":"Награда оказалась больше, чем ожидалось.","vi":"Phần thưởng lớn hơn mong đợi.","fa":"پاداش بیشتر از حد انتظار بود."}]},{"word":"bemerken","en":"to notice","ru":"замечать","vi":"thông báo","fa":"اطلاع دهید","examples":[{"de":"Ich habe seinen Fehler sofort bemerkt.","en":"I noticed his mistake immediately.","ru":"Я сразу заметил его ошибку.","vi":"Tôi nhận ra sai lầm của anh ấy ngay lập tức.","fa":"بلافاصله متوجه اشتباه او شدم."},{"de":"Hast du bemerkt, dass die Tür offen ist?","en":"Did you notice that the door is open?","ru":"Ты заметил, что дверь открыта?","vi":"Bạn có để ý thấy cửa đang mở không?","fa":"متوجه باز بودن در شدی؟"}]},{"word":"bemühen","en":"to make an effort, to try hard","ru":"стараться, прилагать усилия","vi":"phấn đấu","fa":"تلاش کردن","examples":[{"de":"Ich bemühe mich, pünktlich zu sein.","en":"I make an effort to be on time.","ru":"Я стараюсь приходить вовремя.","vi":"Tôi cố gắng đến đúng giờ.","fa":"سعی می کنم به موقع برسم."},{"de":"Sie bemüht sich sehr um eine gute Note.","en":"She tries hard to get a good grade.","ru":"Она старается получить хорошую оценку.","vi":"Cô ấy cố gắng rất nhiều để đạt được điểm cao.","fa":"او خیلی تلاش می کند تا نمره خوبی بگیرد."},{"de":"Wir bemühen uns, Ihnen schnell zu helfen.","en":"We strive to help you quickly.","ru":"Мы стараемся помочь вам быстро.","vi":"Chúng tôi cố gắng giúp bạn nhanh chóng.","fa":"ما در تلاش هستیم تا به سرعت به شما کمک کنیم."}]},{"word":"die Bemühung","en":"effort, endeavour","ru":"старание, усилие, хлопоты","vi":"nỗ lực","fa":"تلاش","examples":[{"de":"Vielen Dank für Ihre Bemühungen.","en":"Thank you very much for your efforts.","ru":"Большое спасибо за ваши старания.","vi":"Cảm ơn sự nỗ lực của bạn.","fa":"از زحمات شما متشکرم."},{"de":"Alle Bemühungen waren leider vergeblich.","en":"Unfortunately all efforts were in vain.","ru":"Все усилия, к сожалению, были напрасны.","vi":"Thật không may, mọi nỗ lực đều vô ích.","fa":"متأسفانه همه تلاش ها بی نتیجه ماند."},{"de":"Ihre Bemühungen wurden endlich belohnt.","en":"Her efforts were finally rewarded.","ru":"Её старания наконец были вознаграждены.","vi":"Những nỗ lực của bạn cuối cùng đã được đền đáp.","fa":"تلاش های شما در نهایت به ثمر نشست."}]},{"word":"benachteiligen","en":"to disadvantage","ru":"ставить в невыгодное положение, ущемлять","vi":"bất lợi","fa":"ضرر","examples":[{"de":"Das alte System benachteiligt arme Familien.","en":"The old system disadvantages poor families.","ru":"Старая система ущемляет бедные семьи.","vi":"Hệ thống cũ gây bất lợi cho các gia đình nghèo.","fa":"سیستم قدیمی خانواده های فقیر را آسیب می رساند."},{"de":"Niemand darf wegen seiner Herkunft benachteiligt werden.","en":"No one may be disadvantaged because of their origin.","ru":"Никого нельзя ущемлять из-за происхождения.","vi":"Không ai phải thiệt thòi vì nguồn gốc của mình.","fa":"هیچ کس نباید به دلیل منشأ خود در معرض خطر قرار گیرد."},{"de":"Solche Regeln benachteiligen kleine Betriebe.","en":"Such rules disadvantage small businesses.","ru":"Такие правила ставят в невыгодное положение малый бизнес.","vi":"Những quy định như vậy khiến các doanh nghiệp nhỏ gặp bất lợi.","fa":"چنین قوانینی کسب و کارهای کوچک را در معرض آسیب قرار می دهد."}]},{"word":"benötigen","en":"to need, require","ru":"нуждаться (в чём-л.)","vi":"cần","fa":"نیاز دارند","examples":[{"de":"Für dieses Rezept benötigen wir frische Eier.","en":"For this recipe we need fresh eggs.","ru":"Для этого рецепта нам нужны свежие яйца.","vi":"Đối với công thức này, chúng ta cần trứng tươi.","fa":"برای این دستور به تخم مرغ تازه نیاز داریم."},{"de":"Ich benötige mehr Zeit, um das zu erledigen.","en":"I need more time to finish this.","ru":"Мне нужно больше времени, чтобы это закончить.","vi":"Tôi cần thêm thời gian để hoàn thành việc này.","fa":"برای انجام این کار به زمان بیشتری نیاز دارم."}]},{"word":"benutzen","en":"to use","ru":"использовать","vi":"sử dụng","fa":"استفاده کنید","examples":[{"de":"Darf ich deinen Computer benutzen?","en":"May I use your computer?","ru":"Можно мне воспользоваться твоим компьютером?","vi":"Tôi có thể sử dụng máy tính của bạn được không?","fa":"آیا می توانم از کامپیوتر شما استفاده کنم؟"},{"de":"Wir benutzen oft öffentliche Verkehrsmittel.","en":"We often use public transport.","ru":"Мы часто пользуемся общественным транспортом.","vi":"Chúng tôi thường sử dụng phương tiện giao thông công cộng.","fa":"ما اغلب از حمل و نقل عمومی استفاده می کنیم."}]},{"word":"der Benutzer","en":"user","ru":"пользователь","vi":"người dùng","fa":"کاربر","examples":[{"de":"Jeder Benutzer braucht einen eigenen Namen.","en":"Every user needs their own name.","ru":"Каждому пользователю нужно собственное имя.","vi":"Mỗi người dùng cần có tên riêng của họ.","fa":"هر کاربر به نام خود نیاز دارد."},{"de":"Die App hat schon über eine Million Benutzer.","en":"The app already has over a million users.","ru":"У приложения уже больше миллиона пользователей.","vi":"Ứng dụng này đã có hơn một triệu người dùng.","fa":"این اپلیکیشن در حال حاضر بیش از یک میلیون کاربر دارد."},{"de":"Als Benutzer kannst du dein Profil selbst ändern.","en":"As a user you can change your own profile.","ru":"Как пользователь ты можешь сам изменить свой профиль.","vi":"Là người dùng, bạn có thể tự thay đổi hồ sơ của mình.","fa":"به عنوان یک کاربر، می توانید خودتان پروفایل خود را تغییر دهید."}]},{"word":"die Benutzerfreundlichkeit","en":"user-friendliness, usability","ru":"удобство пользования, юзабилити","vi":"sự thân thiện với người dùng","fa":"کاربر پسند بودن","examples":[{"de":"Die Benutzerfreundlichkeit der App ist hervorragend.","en":"The user-friendliness of the app is excellent.","ru":"Удобство пользования приложением превосходное.","vi":"Khả năng sử dụng của ứng dụng là tuyệt vời.","fa":"قابلیت استفاده برنامه عالی است."},{"de":"Bei der Entwicklung steht die Benutzerfreundlichkeit im Vordergrund.","en":"User-friendliness is the priority during development.","ru":"При разработке удобство пользования стоит на первом месте.","vi":"Trong quá trình phát triển, trọng tâm là sự thân thiện với người dùng.","fa":"در طول توسعه، تمرکز بر کاربرپسندی است."},{"de":"Die schlechte Benutzerfreundlichkeit ärgert viele Kunden.","en":"The poor usability annoys many customers.","ru":"Плохое удобство пользования раздражает многих клиентов.","vi":"Tính thân thiện với người dùng kém khiến nhiều khách hàng khó chịu.","fa":"کاربرپسندی ضعیف بسیاری از مشتریان را آزار می دهد."}]},{"word":"der Benutzername","en":"a username for logging in to a service","ru":"имя пользователя (для входа в сервис)","vi":"tên người dùng","fa":"نام کاربری","examples":[{"de":"Oft musst du einen Benutzernamen wählen.","en":"Often you have to choose a username.","ru":"Часто приходится выбирать имя пользователя.","vi":"Thường thì bạn phải chọn một tên người dùng.","fa":"اغلب شما باید یک نام کاربری انتخاب کنید."},{"de":"Ich habe meinen Benutzernamen vergessen und kann mich nicht mehr einloggen.","en":"I've forgotten my username and can no longer log in.","ru":"Я забыл своё имя пользователя и больше не могу войти.","vi":"Tôi quên tên người dùng và không thể đăng nhập được nữa.","fa":"نام کاربری خود را فراموش کردم و دیگر نمی توانم وارد شوم."},{"de":"Der Benutzername muss aus mindestens sechs Zeichen bestehen.","en":"The username has to consist of at least six characters.","ru":"Имя пользователя должно состоять минимум из шести символов.","vi":"Tên người dùng phải bao gồm ít nhất sáu ký tự.","fa":"نام کاربری باید حداقل از شش کاراکتر تشکیل شده باشد."}]},{"word":"das Benzin","en":"petrol, gasoline","ru":"бензин","vi":"xăng","fa":"بنزین","examples":[{"de":"Das Auto braucht wenig Benzin.","en":"The car uses little petrol.","ru":"Машина расходует мало бензина.","vi":"Chiếc xe cần ít xăng.","fa":"ماشین به بنزین کمی نیاز دارد."},{"de":"Wir müssen an der Tankstelle Benzin tanken.","en":"We need to fill up with petrol at the gas station.","ru":"Нам нужно заправиться бензином на заправке.","vi":"Chúng tôi phải đổ xăng ở trạm xăng.","fa":"پمپ بنزین باید بنزین بزنیم."}]},{"word":"beobachten","en":"to observe, watch","ru":"наблюдать","vi":"quan sát","fa":"مشاهده کنید","examples":[{"de":"Die Polizei beobachtet das Haus seit Tagen.","en":"The police have been observing the house for days.","ru":"Полиция уже несколько дней наблюдает за домом.","vi":"Cảnh sát đã theo dõi ngôi nhà trong nhiều ngày.","fa":"پلیس چند روزی است که خانه را زیر نظر دارد."},{"de":"Kinder beobachten gern Tiere im Zoo.","en":"Children like to watch animals at the zoo.","ru":"Дети любят наблюдать за животными в зоопарке.","vi":"Trẻ em thích thú ngắm nhìn các loài động vật trong vườn thú.","fa":"کودکان از تماشای حیوانات در باغ وحش لذت می برند."}]},{"word":"bequem","en":"comfortable","ru":"удобный","vi":"thoải mái","fa":"راحت","examples":[{"de":"Dieser Sessel ist sehr bequem.","en":"This armchair is very comfortable.","ru":"Это кресло очень удобное.","vi":"Chiếc ghế bành này rất thoải mái.","fa":"این صندلی بسیار راحت است."},{"de":"Ich trage gern bequeme Schuhe.","en":"I like to wear comfortable shoes.","ru":"Я люблю носить удобную обувь.","vi":"Tôi thích đi giày thoải mái.","fa":"من دوست دارم کفش راحتی بپوشم."}]},{"word":"beraten","en":"to advise","ru":"консультировать, советовать","vi":"khuyên nhủ","fa":"نصیحت کردن","examples":[{"de":"Der Verkäufer berät mich gern beim Kauf.","en":"The salesman is happy to advise me on my purchase.","ru":"Продавец охотно консультирует меня при покупке.","vi":"Người bán sẽ vui lòng tư vấn cho tôi về việc mua hàng.","fa":"فروشنده خوشحال خواهد شد که من را در مورد خرید راهنمایی کند."},{"de":"Ein Anwalt hat uns rechtlich beraten.","en":"A lawyer advised us legally.","ru":"Адвокат проконсультировал нас по правовым вопросам.","vi":"Một luật sư đã cho chúng tôi lời khuyên pháp lý.","fa":"یک وکیل به ما مشاوره حقوقی داد."}]},{"word":"die Beratung","en":"advice, consultation, counselling","ru":"консультация, совет","vi":"lời khuyên","fa":"مشاوره","examples":[{"de":"Die Beratung in der Bank war sehr hilfreich.","en":"The advice at the bank was very helpful.","ru":"Консультация в банке была очень полезной.","vi":"Lời khuyên của ngân hàng rất hữu ích.","fa":"مشاوره در بانک بسیار مفید بود."},{"de":"Für eine genaue Beratung vereinbaren Sie bitte einen Termin.","en":"For detailed advice please arrange an appointment.","ru":"Для подробной консультации запишитесь, пожалуйста, на приём.","vi":"Để được tư vấn chi tiết vui lòng đặt lịch hẹn.","fa":"برای مشاوره دقیق لطفا یک قرار ملاقات بگذارید."},{"de":"Die erste Beratung ist kostenlos.","en":"The first consultation is free.","ru":"Первая консультация бесплатная.","vi":"Buổi tư vấn đầu tiên là miễn phí.","fa":"اولین مشاوره رایگان است."}]},{"word":"berechnen","en":"to calculate","ru":"рассчитывать, вычислять","vi":"tính toán","fa":"محاسبه کنید","examples":[{"de":"Der Taxifahrer berechnet den Preis nach der Entfernung.","en":"The taxi driver calculates the price according to the distance.","ru":"Таксист рассчитывает цену по расстоянию.","vi":"Tài xế taxi tính giá theo quãng đường.","fa":"راننده تاکسی با توجه به مسافت قیمت را محاسبه می کند."},{"de":"Kannst du mir die Kosten berechnen?","en":"Can you calculate the costs for me?","ru":"Можешь рассчитать мне стоимость?","vi":"Bạn có thể tính toán chi phí cho tôi được không?","fa":"می توانید هزینه ها را برای من محاسبه کنید؟"}]},{"word":"die Berechnung","en":"calculation","ru":"вычисление, расчёт","vi":"sự tính toán","fa":"محاسبه","examples":[{"de":"Die Berechnung des Durchschnitts ist einfach.","en":"The calculation of the average is simple.","ru":"Вычисление среднего значения простое.","vi":"Tính toán trung bình là dễ dàng.","fa":"محاسبه میانگین آسان است."},{"de":"Bei der Berechnung ist ein Fehler passiert.","en":"A mistake happened during the calculation.","ru":"В расчёте произошла ошибка.","vi":"Đã xảy ra lỗi trong quá trình tính toán.","fa":"در حین محاسبه خطایی رخ داد."},{"de":"Der Computer übernimmt die ganze Berechnung.","en":"The computer does the entire calculation.","ru":"Компьютер берёт на себя весь расчёт.","vi":"Máy tính thực hiện tất cả các tính toán.","fa":"کامپیوتر تمام محاسبات را انجام می دهد."}]},{"word":"der Bereich","en":"area, field","ru":"область, сфера","vi":"khu vực","fa":"منطقه","examples":[{"de":"Sie arbeitet im Bereich der Medizin.","en":"She works in the field of medicine.","ru":"Она работает в области медицины.","vi":"Cô ấy làm việc trong lĩnh vực y học.","fa":"او در زمینه پزشکی فعالیت می کند."},{"de":"Dieser Bereich des Parks ist für Kinder reserviert.","en":"This area of the park is reserved for children.","ru":"Эта зона парка предназначена для детей.","vi":"Khu vực này của công viên được dành riêng cho trẻ em.","fa":"این منطقه از پارک مخصوص کودکان است."}]},{"word":"bereit","en":"ready","ru":"готовый","vi":"sẵn sàng","fa":"آماده","examples":[{"de":"Bist du bereit für die Prüfung?","en":"Are you ready for the exam?","ru":"Ты готов к экзамену?","vi":"Bạn đã sẵn sàng cho kỳ thi chưa?","fa":"آیا برای امتحان آماده هستید؟"},{"de":"Das Essen ist bereit, wir können anfangen.","en":"The food is ready, we can start.","ru":"Еда готова, можем начинать.","vi":"Thức ăn đã sẵn sàng, chúng ta có thể bắt đầu.","fa":"غذا آماده است، می توانیم شروع کنیم."}]},{"word":"bereits","en":"already","ru":"уже","vi":"rồi","fa":"در حال حاضر","examples":[{"de":"Er ist bereits nach Hause gegangen.","en":"He has already gone home.","ru":"Он уже ушёл домой.","vi":"Anh ấy đã về nhà rồi.","fa":"او قبلاً به خانه رفته است."},{"de":"Wir haben das Problem bereits gelöst.","en":"We have already solved the problem.","ru":"Мы уже решили эту проблему.","vi":"Chúng tôi đã giải quyết được vấn đề.","fa":"ما قبلا مشکل را حل کرده ایم."}]},{"word":"der Berg","en":"mountain","ru":"гора","vi":"ngọn núi","fa":"کوه","examples":[{"de":"Wir wandern jedes Jahr in die Berge.","en":"We go hiking in the mountains every year.","ru":"Мы каждый год ходим в горы.","vi":"Chúng tôi leo núi hàng năm.","fa":"ما هر سال به کوه می رویم."},{"de":"Der höchste Berg Deutschlands ist die Zugspitze.","en":"The highest mountain in Germany is the Zugspitze.","ru":"Самая высокая гора Германии — Цугшпитце.","vi":"Ngọn núi cao nhất ở Đức là Zugspitze.","fa":"بلندترین کوه آلمان، زوگسپیتزه است."}]},{"word":"der Bericht","en":"report","ru":"отчёт; репортаж","vi":"báo cáo","fa":"گزارش","examples":[{"de":"Der Bericht muss bis Freitag fertig sein.","en":"The report has to be finished by Friday.","ru":"Отчёт должен быть готов к пятнице.","vi":"Báo cáo phải được hoàn thành trước thứ Sáu.","fa":"گزارش باید تا روز جمعه آماده شود."},{"de":"Im Bericht standen alle wichtigen Zahlen.","en":"All the important figures were in the report.","ru":"В отчёте были все важные цифры.","vi":"Tất cả những con số quan trọng đều có trong báo cáo.","fa":"همه اعداد مهم در گزارش بود."}]},{"word":"berichten","en":"to report","ru":"сообщать, докладывать","vi":"báo cáo","fa":"گزارش دهید","examples":[{"de":"Die Zeitung berichtet über den Unfall.","en":"The newspaper reports on the accident.","ru":"Газета сообщает об аварии.","vi":"Báo đưa tin về vụ tai nạn.","fa":"این روزنامه از این حادثه خبر می دهد."},{"de":"Er berichtete uns von seiner Reise.","en":"He told us about his trip.","ru":"Он рассказал нам о своей поездке.","vi":"Anh ấy kể cho chúng tôi nghe về chuyến đi của mình.","fa":"از سفرش به ما گفت."}]},{"word":"die Berliner","en":"jam doughnut (Berlin pastry); also: inhabitant of Berlin","ru":"берлинский пончик с начинкой; также: житель Берлина, берлинец","vi":"người Berlin","fa":"برلینی ها","examples":[{"de":"Zu Silvester essen wir traditionell eine Berliner.","en":"On New Year's Eve we traditionally eat a jam doughnut.","ru":"В новогоднюю ночь мы по традиции едим пончик.","vi":"Theo truyền thống, chúng tôi ăn món Berliner vào đêm giao thừa.","fa":"ما به طور سنتی در شب سال نو یک برلینی می خوریم."},{"de":"Die Berliner aus dieser Bäckerei sind besonders frisch.","en":"The doughnuts from this bakery are especially fresh.","ru":"Пончики из этой пекарни особенно свежие.","vi":"Người Berlin ở tiệm bánh này đặc biệt tươi ngon.","fa":"برلینی های این نانوایی به خصوص تازه هستند."},{"de":"Magst du lieber eine Berliner mit Marmelade oder mit Vanille?","en":"Do you prefer a doughnut with jam or with vanilla?","ru":"Ты предпочитаешь пончик с джемом или с ванилью?","vi":"Bạn thích Berliner với mứt hay với vani?","fa":"برلینی را با مربا ترجیح می دهید یا با وانیل؟"}]},{"word":"berücksichtigen","en":"to take into account; to consider","ru":"учитывать; принимать во внимание","vi":"tính đến","fa":"در نظر گرفتن","examples":[{"de":"Bei der Planung müssen wir das Wetter berücksichtigen.","en":"When planning we have to take the weather into account.","ru":"При планировании мы должны учитывать погоду.","vi":"Khi lập kế hoạch, chúng ta phải tính đến thời tiết.","fa":"هنگام برنامه ریزی باید آب و هوا را در نظر بگیریم."},{"de":"Ihre Wünsche werden natürlich berücksichtigt.","en":"Your wishes will of course be taken into account.","ru":"Ваши пожелания, разумеется, будут учтены.","vi":"Mong muốn của bạn tất nhiên sẽ được tính đến.","fa":"البته خواسته های شما مورد توجه قرار خواهد گرفت."}]},{"word":"der Beruf","en":"profession, job","ru":"профессия","vi":"nghề nghiệp","fa":"حرفه","examples":[{"de":"Was ist dein Beruf?","en":"What is your profession?","ru":"Кто ты по профессии?","vi":"Công việc của bạn là gì?","fa":"شغل شما چیست؟"},{"de":"Sie hat ihren Beruf mit Leidenschaft gewählt.","en":"She chose her profession with passion.","ru":"Она выбрала свою профессию с увлечением.","vi":"Cô chọn nghề bằng niềm đam mê.","fa":"او حرفه خود را با علاقه انتخاب کرد."}]},{"word":"beruflich","en":"professional, work-related; on business","ru":"профессиональный, по работе; по служебным делам","vi":"một cách chuyên nghiệp","fa":"به صورت حرفه ای","examples":[{"de":"Was machst du beruflich?","en":"What do you do for a living?","ru":"Кем ты работаешь?","vi":"Bạn làm gì để kiếm sống?","fa":"برای امرار معاش چه می کنید؟"},{"de":"Er ist beruflich viel unterwegs.","en":"He travels a lot for work.","ru":"Он много ездит по работе.","vi":"Anh ấy đi công tác rất nhiều.","fa":"او برای کار زیاد سفر می کند."},{"de":"Sie hat beruflich große Erfolge.","en":"She has great professional success.","ru":"У неё большой профессиональный успех.","vi":"Cô ấy có thành công lớn về mặt chuyên môn.","fa":"او از نظر حرفه ای موفقیت بزرگی دارد."}]},{"word":"die Berufsunfähigkeitsversicherung","en":"occupational disability insurance","ru":"страхование на случай потери трудоспособности","vi":"bảo hiểm tai nạn lao động","fa":"بیمه ناتوانی شغلی","examples":[{"de":"Eine Berufsunfähigkeitsversicherung ist für junge Menschen oft günstiger.","en":"Occupational disability insurance is often cheaper for young people.","ru":"Страхование на случай потери трудоспособности часто дешевле для молодых людей.","vi":"Bảo hiểm khuyết tật nghề nghiệp thường rẻ hơn cho người trẻ.","fa":"بیمه ناتوانی شغلی اغلب برای جوانان ارزان تر است."},{"de":"Er hat eine Berufsunfähigkeitsversicherung abgeschlossen.","en":"He has taken out occupational disability insurance.","ru":"Он оформил страхование на случай потери трудоспособности.","vi":"Anh ấy đã mua bảo hiểm khuyết tật nghề nghiệp.","fa":"بیمه از کار افتادگی شغلی گرفته است."},{"de":"Die Berufsunfähigkeitsversicherung zahlt, wenn man nicht mehr arbeiten kann.","en":"Occupational disability insurance pays out if you can no longer work.","ru":"Такое страхование выплачивает деньги, если ты больше не можешь работать.","vi":"Bảo hiểm khuyết tật nghề nghiệp chi trả nếu bạn không thể làm việc được nữa.","fa":"بیمه از کار افتادگی شغلی اگر دیگر نتوانید کار کنید پرداخت می کند."}]},{"word":"beruhigen","en":"to calm down","ru":"успокаивать","vi":"bình tĩnh","fa":"آرام باش","examples":[{"de":"Die Mutter beruhigte das weinende Kind.","en":"The mother calmed the crying child.","ru":"Мать успокоила плачущего ребёнка.","vi":"Người mẹ dỗ dành đứa trẻ đang khóc.","fa":"مادر کودک گریان را آرام کرد."},{"de":"Beruhige dich, alles wird gut.","en":"Calm down, everything will be fine.","ru":"Успокойся, всё будет хорошо.","vi":"Hãy bình tĩnh, mọi chuyện sẽ ổn thôi.","fa":"آرام باش همه چیز درست خواهد شد."}]},{"word":"berühmt","en":"famous","ru":"знаменитый","vi":"nổi tiếng","fa":"معروف","examples":[{"de":"Dieser Maler ist weltberühmt.","en":"This painter is world-famous.","ru":"Этот художник всемирно известен.","vi":"Họa sĩ này nổi tiếng thế giới.","fa":"این نقاش شهرت جهانی دارد."},{"de":"Die Stadt ist berühmt für ihre Architektur.","en":"The city is famous for its architecture.","ru":"Город знаменит своей архитектурой.","vi":"Thành phố này nổi tiếng với kiến ​​trúc của nó.","fa":"این شهر به دلیل معماری خود مشهور است."}]},{"word":"die Berührung","en":"touch, contact","ru":"прикосновение, касание; контакт (соприкосновение)","vi":"sự chạm vào","fa":"لمس","examples":[{"de":"Eine sanfte Berührung beruhigt.","en":"A gentle touch is calming.","ru":"Нежное прикосновение успокаивает.","vi":"Một cái chạm nhẹ nhàng làm dịu đi.","fa":"یک لمس آرام آرام می کند."},{"de":"Bei Berührung leuchtet der Bildschirm auf.","en":"On touch the screen lights up.","ru":"При касании экран загорается.","vi":"Khi chạm vào, màn hình sẽ sáng lên.","fa":"با لمس، صفحه نمایش روشن می شود."},{"de":"Sie kamen mit fremden Kulturen in Berührung.","en":"They came into contact with foreign cultures.","ru":"Они соприкоснулись с чужими культурами.","vi":"Họ tiếp xúc với các nền văn hóa nước ngoài.","fa":"آنها با فرهنگ های بیگانه در تماس بودند."}]},{"word":"die Besatzung","en":"occupation (military)","ru":"оккупация (военная)","vi":"phi hành đoàn","fa":"خدمه","examples":[{"de":"Nach dem Krieg stand das Land unter ausländischer Besatzung.","en":"After the war the country was under foreign occupation.","ru":"После войны страна находилась под иностранной оккупацией.","vi":"Sau chiến tranh, đất nước bị nước ngoài chiếm đóng.","fa":"پس از جنگ، کشور در اشغال خارجی بود."},{"de":"Die Besatzung dauerte mehrere Jahre.","en":"The occupation lasted several years.","ru":"Оккупация длилась несколько лет.","vi":"Sự chiếm đóng kéo dài vài năm.","fa":"این اشغال چندین سال به طول انجامید."},{"de":"Während der Besatzung war die Hauptstadt in vier Zonen geteilt.","en":"During the occupation the capital was divided into four zones.","ru":"Во время оккупации столица была разделена на четыре зоны.","vi":"Trong thời kỳ chiếm đóng, thủ đô được chia thành bốn khu.","fa":"در زمان اشغال، پایتخت به چهار منطقه تقسیم شد."}]},{"word":"beschädigen","en":"to damage","ru":"повреждать","vi":"thiệt hại","fa":"آسیب","examples":[{"de":"Der Sturm hat das Dach beschädigt.","en":"The storm damaged the roof.","ru":"Буря повредила крышу.","vi":"Cơn bão đã làm hư hỏng mái nhà.","fa":"طوفان به سقف خانه آسیب زد."},{"de":"Bitte beschädige das Buch nicht.","en":"Please don't damage the book.","ru":"Пожалуйста, не повреди книгу.","vi":"Xin đừng làm hỏng cuốn sách.","fa":"لطفا به کتاب آسیب ندهید."}]},{"word":"beschädigt","en":"damaged","ru":"повреждённый","vi":"hư hỏng","fa":"آسیب دیده است","examples":[{"de":"Das Paket kam beschädigt bei mir an.","en":"The parcel arrived damaged at my place.","ru":"Посылка пришла ко мне повреждённой.","vi":"Gói hàng bị hư hỏng.","fa":"بسته آسیب دیده رسید."},{"de":"Die beschädigte Tür lässt sich nicht mehr schließen.","en":"The damaged door can no longer be closed.","ru":"Повреждённую дверь больше нельзя закрыть.","vi":"Cánh cửa bị hư hỏng không thể đóng được nữa.","fa":"درب آسیب دیده دیگر نمی تواند بسته شود."},{"de":"Wir tauschen beschädigte Artikel kostenlos um.","en":"We exchange damaged items free of charge.","ru":"Повреждённые товары мы обмениваем бесплатно.","vi":"Chúng tôi sẽ trao đổi các mặt hàng bị hư hỏng miễn phí.","fa":"ما اقلام آسیب دیده را رایگان تعویض می کنیم."}]},{"word":"beschäftigen","en":"to employ; to occupy oneself with","ru":"нанимать (сотрудников), заниматься (чем-л.)","vi":"tuyển dụng","fa":"استخدام کردن","examples":[{"de":"Die Firma beschäftigt über hundert Mitarbeiter.","en":"The company employs over a hundred employees.","ru":"Компания нанимает более ста сотрудников.","vi":"Công ty có hơn một trăm người.","fa":"این شرکت بیش از صد نفر را استخدام می کند."},{"de":"Ich beschäftige mich gerade mit einem neuen Buch.","en":"I am currently occupied with a new book.","ru":"Я сейчас занимаюсь новой книгой.","vi":"Tôi hiện đang làm việc trên một cuốn sách mới.","fa":"در حال حاضر روی یک کتاب جدید کار می کنم."}]},{"word":"beschäftigt","en":"busy; employed","ru":"занятой; работающий (по найму)","vi":"bận rộn","fa":"مشغول","examples":[{"de":"Tut mir leid, ich bin heute sehr beschäftigt.","en":"I'm sorry, I am very busy today.","ru":"Извини, я сегодня очень занят.","vi":"Xin lỗi, hôm nay tôi rất bận.","fa":"ببخشید امروز خیلی سرم شلوغه"},{"de":"Er ist bei einer großen Bank beschäftigt.","en":"He is employed at a big bank.","ru":"Он работает в крупном банке.","vi":"Anh ấy làm việc cho một ngân hàng lớn.","fa":"او برای یک بانک بزرگ کار می کند."},{"de":"Sie war so beschäftigt, dass sie das Mittagessen vergaß.","en":"She was so busy that she forgot lunch.","ru":"Она была так занята, что забыла об обеде.","vi":"Cô bận quá đến nỗi quên cả bữa trưa.","fa":"آنقدر سرش شلوغ بود که فراموش کرد ناهار بخورد."}]},{"word":"die Beschäftigung","en":"occupation, employment, activity","ru":"занятость, работа; занятие","vi":"việc làm","fa":"استخدام","examples":[{"de":"Er sucht seit Monaten eine feste Beschäftigung.","en":"He has been looking for steady employment for months.","ru":"Он уже несколько месяцев ищет постоянную работу.","vi":"Anh ấy đã tìm kiếm việc làm lâu dài trong nhiều tháng.","fa":"او ماه هاست که به دنبال شغل دائمی است."},{"de":"Lesen ist meine liebste Beschäftigung am Wochenende.","en":"Reading is my favourite activity at the weekend.","ru":"Чтение — моё любимое занятие по выходным.","vi":"Đọc sách là hoạt động cuối tuần yêu thích của tôi.","fa":"خواندن فعالیت مورد علاقه من در آخر هفته است."},{"de":"Die neue Beschäftigung macht ihr großen Spaß.","en":"She really enjoys her new job.","ru":"Её новая работа ей очень нравится.","vi":"Cô ấy thực sự thích công việc mới của mình.","fa":"او واقعاً از شغل جدید خود لذت می برد."}]},{"word":"der Bescheid","en":"notification, information","ru":"уведомление, сообщение","vi":"thông báo","fa":"اطلاعیه","examples":[{"de":"Ich gebe dir morgen Bescheid.","en":"I'll let you know tomorrow.","ru":"Я дам тебе знать завтра.","vi":"Tôi sẽ cho bạn biết vào ngày mai.","fa":"فردا بهت خبر میدم"},{"de":"Wir haben noch keinen Bescheid vom Amt bekommen.","en":"We haven't received any notification from the office yet.","ru":"Мы ещё не получили уведомление от ведомства.","vi":"Chúng tôi chưa nhận được bất kỳ thông báo nào từ văn phòng.","fa":"ما هنوز هیچ اطلاعیه ای از دفتر دریافت نکرده ایم."}]},{"word":"bescheinigen","en":"to certify, to confirm in writing","ru":"удостоверять, подтверждать (письменно)","vi":"chứng nhận","fa":"گواهی کند","examples":[{"de":"Der Arzt bescheinigt mir, dass ich krank bin.","en":"The doctor certifies that I am ill.","ru":"Врач удостоверяет, что я болен.","vi":"Bác sĩ xác nhận rằng tôi bị bệnh.","fa":"دکتر تایید می کند که من بیمار هستم."},{"de":"Bitte bescheinigen Sie mir die Teilnahme am Kurs.","en":"Please confirm my participation in the course in writing.","ru":"Пожалуйста, подтвердите письменно моё участие в курсе.","vi":"Vui lòng xác nhận việc bạn tham gia khóa học.","fa":"لطفا شرکت خود را در دوره تایید نمایید."},{"de":"Die Schule bescheinigte ihm sehr gute Leistungen.","en":"The school certified that he had very good results.","ru":"Школа подтвердила, что у него были очень хорошие результаты.","vi":"Nhà trường chứng nhận rằng anh ấy đã thể hiện rất tốt.","fa":"مدرسه تأیید کرد که او عملکرد بسیار خوبی داشت."}]},{"word":"beschließen","en":"to decide","ru":"решать, принимать решение","vi":"quyết định","fa":"تصمیم بگیرند","examples":[{"de":"Wir haben beschlossen, umzuziehen.","en":"We have decided to move.","ru":"Мы решили переехать.","vi":"Chúng tôi quyết định di chuyển.","fa":"تصمیم گرفتیم حرکت کنیم."},{"de":"Der Rat beschließt neue Regeln für die Stadt.","en":"The council decides on new rules for the city.","ru":"Совет принимает новые правила для города.","vi":"Hội đồng quyết định các quy định mới cho thành phố.","fa":"شورا در مورد قوانین جدید برای شهر تصمیم می گیرد."}]},{"word":"beschränken","en":"to limit, restrict","ru":"ограничивать","vi":"giới hạn","fa":"محدود کردن","examples":[{"de":"Die Stadt beschränkt den Verkehr in der Innenstadt.","en":"The city restricts traffic in the city center.","ru":"Город ограничивает движение в центре.","vi":"Thành phố đang hạn chế giao thông ở trung tâm thành phố.","fa":"شهر تردد در مرکز شهر را محدود کرده است."},{"de":"Wir müssen unsere Ausgaben beschränken.","en":"We need to limit our expenses.","ru":"Нам нужно ограничить наши расходы.","vi":"Chúng ta phải hạn chế chi tiêu.","fa":"ما باید هزینه هایمان را محدود کنیم."}]},{"word":"beschreiben","en":"to describe","ru":"описывать","vi":"mô tả","fa":"توصیف کنید","examples":[{"de":"Kannst du mir den Weg beschreiben?","en":"Can you describe the way to me?","ru":"Можешь описать мне дорогу?","vi":"Bạn có thể mô tả đường đi cho tôi được không?","fa":"میشه راه رو برام تعریف کنی؟"},{"de":"Sie beschrieb ihre Gefühle sehr genau.","en":"She described her feelings very precisely.","ru":"Она очень точно описала свои чувства.","vi":"Cô mô tả cảm xúc của mình rất chi tiết.","fa":"او احساسات خود را با جزئیات کامل توصیف کرد."}]},{"word":"die Beschreibung","en":"description","ru":"описание","vi":"mô tả","fa":"توضیحات","examples":[{"de":"Die Beschreibung des Weges war sehr genau.","en":"The description of the route was very precise.","ru":"Описание маршрута было очень точным.","vi":"Mô tả về tuyến đường rất chính xác.","fa":"شرح مسیر بسیار دقیق بود."},{"de":"Lies bitte die Beschreibung des Produkts.","en":"Please read the description of the product.","ru":"Прочитайте, пожалуйста, описание товара.","vi":"Vui lòng đọc mô tả của sản phẩm.","fa":"لطفا توضیحات محصول را مطالعه فرمایید."},{"de":"Ohne eine gute Beschreibung finde ich das Haus nicht.","en":"Without a good description I will not find the house.","ru":"Без хорошего описания я не найду дом.","vi":"Tôi không thể tìm thấy ngôi nhà mà không có mô tả hay.","fa":"من نمی توانم خانه را بدون شرح خوب پیدا کنم."}]},{"word":"die Beschwerde","en":"complaint","ru":"жалоба","vi":"khiếu nại","fa":"شکایت","examples":[{"de":"Ich möchte eine Beschwerde einreichen.","en":"I would like to file a complaint.","ru":"Я хотел бы подать жалобу.","vi":"Tôi muốn nộp đơn khiếu nại.","fa":"من می خواهم شکایت کنم."},{"de":"Nach mehreren Beschwerden wurde der Lärm endlich leiser.","en":"After several complaints the noise finally got quieter.","ru":"После нескольких жалоб шум наконец стал тише.","vi":"Sau vài lần phàn nàn, tiếng ồn ào cuối cùng cũng lắng xuống.","fa":"پس از چندین بار شکایت، سر و صدا در نهایت خاموش شد."}]},{"word":"der Besen","en":"broom","ru":"метла, веник","vi":"cái chổi","fa":"جارو","examples":[{"de":"Hol bitte den Besen aus der Küche.","en":"Please fetch the broom from the kitchen.","ru":"Принеси, пожалуйста, метлу из кухни.","vi":"Vui lòng lấy chổi từ nhà bếp.","fa":"لطفا جارو را از آشپزخانه بیاورید."},{"de":"Mit dem Besen fege ich den Hof.","en":"I sweep the yard with the broom.","ru":"Я подметаю двор метлой.","vi":"Tôi quét sân bằng chổi.","fa":"با جارو حیاط را جارو می کنم."},{"de":"Der Besen steht hinter der Tür.","en":"The broom is standing behind the door.","ru":"Метла стоит за дверью.","vi":"Cây chổi ở đằng sau cánh cửa.","fa":"جارو پشت در است."}]},{"word":"besetzen","en":"to occupy","ru":"занимать","vi":"chiếm giữ","fa":"را اشغال کند","examples":[{"de":"Alle Plätze im Zug waren besetzt.","en":"All the seats on the train were occupied.","ru":"Все места в поезде были заняты.","vi":"Tất cả chỗ ngồi trên tàu đều đã có người ngồi.","fa":"تمام صندلی های قطار اشغال شده بود."},{"de":"Die Toilette ist gerade besetzt.","en":"The toilet is currently occupied.","ru":"Туалет сейчас занят.","vi":"Nhà vệ sinh hiện đang có người sử dụng.","fa":"سرویس بهداشتی در حال حاضر اشغال است."}]},{"word":"besichtigen","en":"to visit, view (a sight)","ru":"осматривать (достопримечательности)","vi":"chuyến thăm","fa":"بازدید کنید","examples":[{"de":"Wir wollen morgen das Schloss besichtigen.","en":"We want to visit the castle tomorrow.","ru":"Мы хотим завтра осмотреть замок.","vi":"Chúng tôi muốn đến thăm lâu đài vào ngày mai.","fa":"فردا می خواهیم از قلعه دیدن کنیم."},{"de":"Touristen besichtigen gern die alte Kirche.","en":"Tourists like to visit the old church.","ru":"Туристы любят осматривать старую церковь.","vi":"Khách du lịch thích đến thăm nhà thờ cổ.","fa":"گردشگران دوست دارند از کلیسای قدیمی دیدن کنند."}]},{"word":"besiegen","en":"to defeat","ru":"побеждать, одерживать победу над","vi":"đánh bại","fa":"شکست","examples":[{"de":"Das kleine Heer konnte den großen Feind besiegen.","en":"The small army managed to defeat the great enemy.","ru":"Небольшому войску удалось победить великого врага.","vi":"Đội quân nhỏ đã có thể đánh bại kẻ thù lớn.","fa":"ارتش کوچک توانست دشمن بزرگ را شکست دهد."},{"de":"Niemand glaubte, dass sie den König besiegen würden.","en":"No one believed they would defeat the king.","ru":"Никто не верил, что они победят короля.","vi":"Không ai tin rằng họ sẽ đánh bại được nhà vua.","fa":"هیچ کس باور نمی کرد که شاه را شکست دهند."},{"de":"Nachdem sie den Gegner besiegt hatten, schlossen sie Frieden.","en":"After they had defeated the opponent, they made peace.","ru":"После того как они победили противника, они заключили мир.","vi":"Sau khi đánh bại kẻ thù, họ đã làm hòa.","fa":"پس از غلبه بر دشمن، صلح کردند."}]},{"word":"besitzen","en":"to own, possess","ru":"владеть","vi":"sở hữu","fa":"خود","examples":[{"de":"Meine Familie besitzt ein kleines Haus auf dem Land.","en":"My family owns a small house in the countryside.","ru":"Моя семья владеет небольшим домом за городом.","vi":"Gia đình tôi sở hữu một ngôi nhà nhỏ ở nông thôn.","fa":"خانواده من یک خانه کوچک در کشور دارند."},{"de":"Er besitzt zwei Autos.","en":"He owns two cars.","ru":"У него есть две машины.","vi":"Anh ấy sở hữu hai chiếc ô tô.","fa":"او دو ماشین دارد."}]},{"word":"besonder","en":"special, particular","ru":"особый, особенный","vi":"đặc biệt","fa":"خاص","examples":[{"de":"Heute ist ein ganz besonderer Tag für uns.","en":"Today is a very special day for us.","ru":"Сегодня для нас очень особенный день.","vi":"Hôm nay là một ngày rất đặc biệt đối với chúng tôi.","fa":"امروز یک روز بسیار ویژه برای ما است."},{"de":"Sie hat eine besondere Begabung für Sprachen.","en":"She has a special talent for languages.","ru":"У неё особый талант к языкам.","vi":"Cô có năng khiếu đặc biệt về ngôn ngữ.","fa":"او استعداد خاصی در زبان دارد."},{"de":"Es gab keinen besonderen Grund für seine Absage.","en":"There was no particular reason for his cancellation.","ru":"Для его отказа не было особой причины.","vi":"Không có lý do cụ thể nào cho việc hủy bỏ của anh ấy.","fa":"دلیل خاصی برای انصراف او وجود نداشت."}]},{"word":"besonder-","en":"special, particular","ru":"особенный, особый","vi":"đặc biệt-","fa":"ویژه-","examples":[{"de":"Das war ein besonderer Tag für mich.","en":"That was a special day for me.","ru":"Это был особенный день для меня.","vi":"Đó là một ngày đặc biệt đối với tôi.","fa":"آن روز برای من روز خاصی بود."},{"de":"Ich mag besonders den Sommer.","en":"I especially like summer.","ru":"Мне особенно нравится лето.","vi":"Tôi đặc biệt thích mùa hè.","fa":"من به خصوص تابستان را دوست دارم."}]},{"word":"besorgen","en":"to get, procure","ru":"доставать, приобретать","vi":"nhận được","fa":"دریافت کنید","examples":[{"de":"Kannst du mir eine Fahrkarte besorgen?","en":"Can you get me a ticket?","ru":"Можешь достать мне билет?","vi":"Bạn có thể cho tôi một vé được không?","fa":"می توانید برای من بلیط بگیرید؟"},{"de":"Ich muss noch Brot für morgen besorgen.","en":"I still need to get bread for tomorrow.","ru":"Мне ещё нужно купить хлеб на завтра.","vi":"Tôi vẫn phải lấy bánh mì cho ngày mai.","fa":"من هنوز باید برای فردا نان بیاورم."}]},{"word":"die Besorgung","en":"errand","ru":"поручение, дело (по хозяйству)","vi":"việc vặt","fa":"وظیفه","examples":[{"de":"Ich muss noch ein paar Besorgungen machen.","en":"I still have to run a few errands.","ru":"Мне ещё нужно сделать несколько дел.","vi":"Tôi vẫn còn vài việc phải làm.","fa":"من هنوز چند کار برای انجام دادن دارم."},{"de":"Nach der Arbeit erledigt sie ihre Besorgungen.","en":"After work she runs her errands.","ru":"После работы она занимается своими делами.","vi":"Sau giờ làm việc, cô ấy chạy việc vặt của mình.","fa":"بعد از کار او کارهایش را انجام می دهد."},{"de":"Kannst du eine Besorgung für mich machen?","en":"Can you run an errand for me?","ru":"Ты можешь выполнить для меня одно поручение?","vi":"Bạn có thể chạy việc vặt cho tôi được không?","fa":"آیا می توانی برای من مأموریتی انجام دهی؟"}]},{"word":"besprechen","en":"to discuss","ru":"обсуждать","vi":"thảo luận","fa":"بحث کنید","examples":[{"de":"Wir sollten die Details morgen besprechen.","en":"We should discuss the details tomorrow.","ru":"Нам стоит обсудить детали завтра.","vi":"Chúng ta nên thảo luận chi tiết vào ngày mai.","fa":"فردا باید درباره جزئیات صحبت کنیم."},{"de":"Der Chef bespricht die Probleme mit dem Team.","en":"The boss discusses the problems with the team.","ru":"Начальник обсуждает проблемы с командой.","vi":"Sếp thảo luận các vấn đề với nhóm.","fa":"رئیس مشکلات را با تیم در میان می گذارد."}]},{"word":"die Besprechung","en":"meeting","ru":"совещание, обсуждение","vi":"cuộc họp","fa":"جلسه","examples":[{"de":"Die Besprechung beginnt um zehn Uhr im großen Konferenzraum.","en":"The meeting starts at ten o'clock in the large conference room.","ru":"Совещание начинается в десять часов в большом конференц-зале.","vi":"Cuộc họp bắt đầu lúc mười giờ trong phòng họp lớn.","fa":"جلسه راس ساعت ده در سالن بزرگ کنفرانس آغاز می شود."},{"de":"Leider muss ich die Besprechung auf nächste Woche verschieben.","en":"Unfortunately, I have to postpone the meeting to next week.","ru":"К сожалению, мне придётся перенести совещание на следующую неделю.","vi":"Thật không may là tôi phải hoãn cuộc họp sang tuần sau.","fa":"متاسفانه باید جلسه را به هفته آینده موکول کنم."},{"de":"Während der Besprechung wurden mehrere wichtige Entscheidungen getroffen.","en":"Several important decisions were made during the meeting.","ru":"Во время совещания было принято несколько важных решений.","vi":"Một số quyết định quan trọng đã được đưa ra trong cuộc họp.","fa":"در این جلسه چند تصمیم مهم اتخاذ شد."}]},{"word":"die Besserung","en":"improvement, recovery","ru":"улучшение, выздоровление","vi":"sự cải tiến","fa":"بهبود","examples":[{"de":"Gute Besserung!","en":"Get well soon!","ru":"Выздоравливай!","vi":"Hãy sớm khỏe lại!","fa":"زود خوب شو"},{"de":"Nach der Operation zeigte er schnelle Besserung.","en":"After the operation he showed rapid improvement.","ru":"После операции он быстро пошёл на поправку.","vi":"Sau cuộc phẫu thuật, anh ấy đã cho thấy sự cải thiện nhanh chóng.","fa":"پس از عمل او بهبود سریعی را نشان داد."}]},{"word":"bestätigen","en":"to confirm","ru":"подтверждать","vi":"xác nhận","fa":"تایید کنید","examples":[{"de":"Bitte bestätigen Sie den Termin per E-Mail.","en":"Please confirm the appointment by email.","ru":"Пожалуйста, подтвердите встречу по электронной почте.","vi":"Vui lòng xác nhận cuộc hẹn qua email.","fa":"لطفا قرار ملاقات را از طریق ایمیل تایید کنید."},{"de":"Der Arzt bestätigte die Diagnose.","en":"The doctor confirmed the diagnosis.","ru":"Врач подтвердил диагноз.","vi":"Bác sĩ xác nhận chẩn đoán.","fa":"دکتر تشخیص را تایید کرد."}]},{"word":"die Bestätigung","en":"confirmation","ru":"подтверждение","vi":"sự xác nhận","fa":"تایید","examples":[{"de":"Sie erhalten eine Bestätigung per E-Mail.","en":"You will receive a confirmation by email.","ru":"Вы получите подтверждение по электронной почте.","vi":"Bạn sẽ nhận được xác nhận qua email.","fa":"شما یک تاییدیه از طریق ایمیل دریافت خواهید کرد."},{"de":"Ohne schriftliche Bestätigung gilt der Termin nicht.","en":"Without written confirmation the appointment is not valid.","ru":"Без письменного подтверждения запись недействительна.","vi":"Việc bổ nhiệm không có hiệu lực nếu không có xác nhận bằng văn bản.","fa":"قرار ملاقات بدون تایید کتبی معتبر نیست."},{"de":"Ich warte noch auf die Bestätigung der Buchung.","en":"I am still waiting for confirmation of the booking.","ru":"Я всё ещё жду подтверждения бронирования.","vi":"Tôi vẫn đang chờ xác nhận đặt phòng.","fa":"من هنوز منتظر تایید رزرو هستم."}]},{"word":"bestehen","en":"to pass (an exam); to exist, consist","ru":"сдать (экзамен); существовать, состоять","vi":"tồn tại","fa":"وجود داشته باشد","examples":[{"de":"Ich habe die Prüfung bestanden!","en":"I passed the exam!","ru":"Я сдал экзамен!","vi":"Tôi đã vượt qua kỳ thi!","fa":"من در امتحان قبول شدم!"},{"de":"Das Team besteht aus zehn Mitgliedern.","en":"The team consists of ten members.","ru":"Команда состоит из десяти человек.","vi":"Đội ngũ bao gồm mười thành viên.","fa":"تیم متشکل از ده نفر است."}]},{"word":"bestehen aus","en":"to consist of","ru":"состоять из","vi":"bao gồm","fa":"متشکل از","examples":[{"de":"Das Team besteht aus fünf Personen.","en":"The team consists of five people.","ru":"Команда состоит из пяти человек.","vi":"Đội gồm có năm người.","fa":"تیم متشکل از پنج نفر است."},{"de":"Wasser besteht aus Wasserstoff und Sauerstoff.","en":"Water consists of hydrogen and oxygen.","ru":"Вода состоит из водорода и кислорода.","vi":"Nước bao gồm hydro và oxy.","fa":"آب از هیدروژن و اکسیژن تشکیل شده است."}]},{"word":"bestellen","en":"to order","ru":"заказывать","vi":"đặt hàng","fa":"سفارش دهید","examples":[{"de":"Wir bestellen jetzt das Essen.","en":"We are ordering the food now.","ru":"Мы сейчас заказываем еду.","vi":"Chúng ta sẽ gọi đồ ăn ngay bây giờ.","fa":"ما الان غذا را سفارش می دهیم."},{"de":"Sie hat ein neues Buch im Internet bestellt.","en":"She ordered a new book online.","ru":"Она заказала новую книгу в интернете.","vi":"Cô ấy đặt mua một cuốn sách mới trực tuyến.","fa":"او یک کتاب جدید آنلاین سفارش داد."}]},{"word":"die Bestellung","en":"order (purchase)","ru":"заказ (покупка)","vi":"thứ tự","fa":"سفارش","examples":[{"de":"Ihre Bestellung wird in drei Tagen geliefert.","en":"Your order will be delivered in three days.","ru":"Ваш заказ будет доставлен через три дня.","vi":"Đơn đặt hàng của bạn sẽ được giao trong ba ngày.","fa":"سفارش شما سه روز دیگر تحویل خواهد شد."},{"de":"Ich möchte meine Bestellung leider stornieren.","en":"Unfortunately I would like to cancel my order.","ru":"К сожалению, я хотел бы отменить свой заказ.","vi":"Thật không may, tôi muốn hủy đơn hàng của mình.","fa":"متأسفانه من می خواهم سفارش خود را لغو کنم."},{"de":"Der Kellner nahm unsere Bestellung auf.","en":"The waiter took our order.","ru":"Официант принял наш заказ.","vi":"Người phục vụ nhận đơn đặt hàng của chúng tôi.","fa":"گارسون سفارش ما را گرفت."}]},{"word":"bestimmt","en":"certain; definitely","ru":"определённый, наверняка","vi":"xác định","fa":"تعیین شده است","examples":[{"de":"Er kommt bestimmt zur Party.","en":"He will definitely come to the party.","ru":"Он наверняка придёт на вечеринку.","vi":"Anh ấy chắc chắn sẽ đến dự bữa tiệc.","fa":"او قطعا به مهمانی خواهد آمد."},{"de":"Es gibt bestimmte Regeln, die wir befolgen müssen.","en":"There are certain rules that we have to follow.","ru":"Есть определённые правила, которым мы должны следовать.","vi":"Có những quy tắc nhất định chúng ta phải tuân theo.","fa":"قوانین خاصی وجود دارد که باید از آنها پیروی کنیم."}]},{"word":"bestrafen","en":"to punish","ru":"наказывать","vi":"trừng phạt","fa":"مجازات","examples":[{"de":"Die Eltern bestrafen das Kind für die Lüge.","en":"The parents punish the child for the lie.","ru":"Родители наказывают ребёнка за ложь.","vi":"Cha mẹ trừng phạt con vì nói dối.","fa":"والدین کودک را به خاطر دروغ گفتن تنبیه می کنند."},{"de":"Der Fahrer wurde für das Falschparken bestraft.","en":"The driver was punished for parking illegally.","ru":"Водителя наказали за неправильную парковку.","vi":"Tài xế bị phạt vì đỗ xe trái phép.","fa":"راننده به دلیل پارک غیر مجاز جریمه شد."}]},{"word":"besuchen","en":"to visit","ru":"посещать","vi":"chuyến thăm","fa":"بازدید کنید","examples":[{"de":"Wir besuchen am Wochenende unsere Großeltern.","en":"We are visiting our grandparents at the weekend.","ru":"Мы навещаем бабушку с дедушкой на выходных.","vi":"Chúng tôi đến thăm ông bà vào cuối tuần.","fa":"آخر هفته به پدربزرگ و مادربزرگمان می‌رویم."},{"de":"Sie hat viele Länder in Europa besucht.","en":"She has visited many countries in Europe.","ru":"Она посетила много стран в Европе.","vi":"Cô đã đến thăm nhiều nước ở châu Âu.","fa":"او از بسیاری از کشورهای اروپایی بازدید کرده است."}]},{"word":"beteiligen","en":"to involve; to take part (in)","ru":"привлекать (к участию); участвовать (в)","vi":"tham gia","fa":"شرکت کنند","examples":[{"de":"Viele Bürger beteiligen sich an der Diskussion.","en":"Many citizens take part in the discussion.","ru":"Многие граждане участвуют в обсуждении.","vi":"Nhiều người dân tham gia thảo luận.","fa":"بسیاری از شهروندان در بحث شرکت می کنند."},{"de":"Wir möchten alle Mitarbeiter an der Entscheidung beteiligen.","en":"We would like to involve all employees in the decision.","ru":"Мы хотели бы привлечь всех сотрудников к решению.","vi":"Chúng tôi muốn tất cả nhân viên tham gia vào quyết định.","fa":"ما می خواهیم همه کارمندان را در تصمیم گیری مشارکت دهیم."},{"de":"An dem Projekt sind drei Universitäten beteiligt.","en":"Three universities are involved in the project.","ru":"В проекте участвуют три университета.","vi":"Ba trường đại học tham gia vào dự án.","fa":"سه دانشگاه در این پروژه مشارکت دارند."}]},{"word":"der Beton","en":"concrete","ru":"бетон","vi":"bê tông","fa":"بتن","examples":[{"de":"Die Brücke ist aus Beton gebaut.","en":"The bridge is built of concrete.","ru":"Мост построен из бетона.","vi":"Cây cầu được làm bằng bê tông.","fa":"پل از بتن ساخته شده است."},{"de":"Der Beton muss erst einige Tage trocknen.","en":"The concrete must dry for a few days first.","ru":"Сначала бетон должен сохнуть несколько дней.","vi":"Bê tông cần khô trong vài ngày.","fa":"بتن باید چند روز خشک شود."},{"de":"Sie gossen den Beton für das Fundament.","en":"They poured the concrete for the foundation.","ru":"Они залили бетон для фундамента.","vi":"Họ đổ bê tông làm móng.","fa":"بتن را برای پی ریختند."}]},{"word":"betonen","en":"to emphasise; to stress","ru":"подчёркивать","vi":"nhấn mạnh","fa":"تاکید کنید","examples":[{"de":"Der Lehrer betonte, wie wichtig die Hausaufgaben sind.","en":"The teacher stressed how important the homework is.","ru":"Учитель подчеркнул, как важна домашняя работа.","vi":"Giáo viên nhấn mạnh tầm quan trọng của bài tập về nhà.","fa":"معلم بر اهمیت تکالیف تاکید کرد."},{"de":"Ich möchte noch einmal betonen, dass das kein Scherz ist.","en":"I would like to emphasise once again that this is not a joke.","ru":"Я хочу ещё раз подчеркнуть, что это не шутка.","vi":"Tôi muốn nhắc lại rằng đây không phải là một trò đùa.","fa":"من می خواهم تکرار کنم که این یک شوخی نیست."}]},{"word":"betrachten","en":"to look at; to regard; to consider","ru":"рассматривать; смотреть","vi":"xem xét","fa":"در نظر بگیرید","examples":[{"de":"Sie betrachtete das Gemälde lange und still.","en":"She looked at the painting for a long time in silence.","ru":"Она долго и молча рассматривала картину.","vi":"Cô lặng lẽ nhìn bức tranh một lúc lâu.","fa":"بلند و آرام به نقاشی نگاه کرد."},{"de":"Ich betrachte ihn als guten Freund.","en":"I regard him as a good friend.","ru":"Я считаю его хорошим другом.","vi":"Tôi coi anh ấy là một người bạn tốt.","fa":"من او را دوست خوبی می دانم."}]},{"word":"der Betrag","en":"amount (of money)","ru":"сумма","vi":"số tiền","fa":"مقدار","examples":[{"de":"Bitte überweisen Sie den Betrag bis Freitag.","en":"Please transfer the amount by Friday.","ru":"Пожалуйста, переведите сумму до пятницы.","vi":"Vui lòng chuyển số tiền trước thứ Sáu.","fa":"لطفا تا جمعه مبلغ را واریز کنید."},{"de":"Der Gesamtbetrag beträgt 250 Euro.","en":"The total amount is 250 euros.","ru":"Общая сумма составляет 250 евро.","vi":"Tổng số tiền là 250 euro.","fa":"مبلغ کل 250 یورو است."}]},{"word":"betreuen","en":"to look after, care for","ru":"заботиться, присматривать","vi":"chăm sóc","fa":"مراقبت از","examples":[{"de":"Sie betreut ältere Menschen im Pflegeheim.","en":"She cares for elderly people in the nursing home.","ru":"Она заботится о пожилых людях в доме престарелых.","vi":"Cô chăm sóc người già trong viện dưỡng lão.","fa":"او از افراد مسن در خانه های سالمندان مراقبت می کند."},{"de":"Wer betreut die Kinder heute Nachmittag?","en":"Who is looking after the children this afternoon?","ru":"Кто присматривает за детьми сегодня днём?","vi":"Chiều nay ai trông trẻ?","fa":"چه کسی امروز بعد از ظهر از بچه ها مراقبت می کند؟"}]},{"word":"der Betreuer","en":"carer, supervisor, mentor (male)","ru":"воспитатель, куратор, наставник (мужчина)","vi":"người giám sát","fa":"سرپرست","examples":[{"de":"Der Betreuer kümmert sich um die Kinder im Ferienlager.","en":"The supervisor looks after the children at the holiday camp.","ru":"Воспитатель присматривает за детьми в летнем лагере.","vi":"Người giám sát chăm sóc trẻ em tại trại nghỉ lễ.","fa":"سرپرست از کودکان در کمپ تعطیلات مراقبت می کند."},{"de":"Mein Betreuer an der Universität hat mir sehr geholfen.","en":"My supervisor at the university helped me a lot.","ru":"Мой куратор в университете мне очень помог.","vi":"Người hướng dẫn của tôi ở trường đại học đã giúp đỡ tôi rất nhiều.","fa":"استاد راهنمایم در دانشگاه خیلی به من کمک کرد."},{"de":"Der Betreuer begleitet die Gruppe auf dem Ausflug.","en":"The supervisor accompanies the group on the trip.","ru":"Наставник сопровождает группу в поездке.","vi":"Người hướng dẫn đồng hành cùng đoàn trong chuyến tham quan.","fa":"سرپرست گروه را در سفر همراهی می کند."}]},{"word":"die Betreuerin","en":"carer, supervisor, mentor (female)","ru":"воспитательница, куратор, наставница (женщина)","vi":"người chăm sóc","fa":"مراقب","examples":[{"de":"Die Betreuerin liest den Kindern jeden Abend eine Geschichte vor.","en":"The carer reads the children a story every evening.","ru":"Воспитательница каждый вечер читает детям сказку.","vi":"Người chăm sóc đọc truyện cho trẻ nghe vào mỗi buổi tối.","fa":"مراقب هر شب برای بچه ها قصه می خواند."},{"de":"Unsere Betreuerin im Heim ist sehr geduldig.","en":"Our carer at the home is very patient.","ru":"Наша воспитательница в доме очень терпеливая.","vi":"Người chăm sóc tại nhà của chúng tôi rất kiên nhẫn.","fa":"مراقب ما در خانه بسیار صبور است."},{"de":"Die Betreuerin organisierte ein Spiel für die Gruppe.","en":"The supervisor organised a game for the group.","ru":"Наставница организовала для группы игру.","vi":"Người giám sát tổ chức một trò chơi cho nhóm.","fa":"سرپرست یک بازی برای گروه ترتیب داد."}]},{"word":"die Betreuung","en":"care, supervision, support","ru":"уход, присмотр, поддержка, сопровождение","vi":"sự chăm sóc","fa":"مراقبت","examples":[{"de":"Die Betreuung der Kinder übernimmt am Nachmittag meine Mutter.","en":"My mother takes over the care of the children in the afternoon.","ru":"Днём уход за детьми берёт на себя моя мама.","vi":"Mẹ tôi chăm sóc các con vào buổi chiều.","fa":"مادرم بعد از ظهر از بچه ها مراقبت می کند."},{"de":"Für ältere Menschen gibt es eine professionelle Betreuung zu Hause.","en":"There is professional care at home for elderly people.","ru":"Для пожилых людей есть профессиональный уход на дому.","vi":"Có dịch vụ chăm sóc chuyên nghiệp tại nhà cho người lớn tuổi.","fa":"مراقبت حرفه ای در خانه برای افراد مسن وجود دارد."},{"de":"Die ärztliche Betreuung im Krankenhaus war ausgezeichnet.","en":"The medical care in the hospital was excellent.","ru":"Медицинский уход в больнице был превосходным.","vi":"Dịch vụ chăm sóc y tế tại bệnh viện rất tuyệt vời.","fa":"مراقبت های پزشکی در بیمارستان عالی بود."}]},{"word":"der Betrieb","en":"company, business operation","ru":"предприятие, производство","vi":"hoạt động","fa":"عملیات","examples":[{"de":"Mein Vater arbeitet in einem großen Betrieb.","en":"My father works in a large company.","ru":"Мой отец работает на крупном предприятии.","vi":"Bố tôi làm việc ở một công ty lớn.","fa":"پدرم در یک شرکت بزرگ کار می کند."},{"de":"Die Maschine ist außer Betrieb.","en":"The machine is out of operation.","ru":"Машина не работает.","vi":"Máy bị hỏng.","fa":"دستگاه از کار افتاده است."}]},{"word":"die Betriebsrätin","en":"works council member (female)","ru":"член производственного совета (женщина)","vi":"ủy viên hội đồng công trình","fa":"شورای کار","examples":[{"de":"Die Betriebsrätin vertritt die Interessen der Angestellten.","en":"The works council member represents the employees' interests.","ru":"Член производственного совета представляет интересы сотрудников.","vi":"Hội đồng công trình đại diện cho lợi ích của người lao động.","fa":"شوراي كار نماينده منافع كاركنان است."},{"de":"Unsere Betriebsrätin hat ein Treffen mit der Geschäftsführung organisiert.","en":"Our works council member organized a meeting with management.","ru":"Наш представитель производственного совета организовала встречу с руководством.","vi":"Thành viên hội đồng công trình của chúng tôi đã tổ chức một cuộc họp với ban quản lý.","fa":"عضو شورای کار ما جلسه ای با مدیریت ترتیب داد."}]},{"word":"betrügen","en":"to deceive, cheat","ru":"обманывать","vi":"gian lận","fa":"تقلب","examples":[{"de":"Er hat seine Geschäftspartner betrogen.","en":"He deceived his business partners.","ru":"Он обманул своих деловых партнёров.","vi":"Anh ta đã lừa dối các đối tác kinh doanh của mình.","fa":"او به شرکای تجاری خود خیانت کرد."},{"de":"Sie fühlte sich von ihrem Freund betrogen.","en":"She felt cheated by her boyfriend.","ru":"Она чувствовала себя обманутой своим парнем.","vi":"Cô cảm thấy bị bạn trai phản bội.","fa":"او احساس می کرد که توسط دوست پسرش خیانت شده است."}]},{"word":"betrunken","en":"drunk","ru":"пьяный","vi":"say rượu","fa":"مست","examples":[{"de":"Er war zu betrunken, um selbst zu fahren.","en":"He was too drunk to drive himself.","ru":"Он был слишком пьян, чтобы вести машину самому.","vi":"Anh ta quá say để tự lái xe.","fa":"او آنقدر مست بود که خودش نمی توانست رانندگی کند."},{"de":"Man sollte nicht betrunken Auto fahren.","en":"One shouldn't drive drunk.","ru":"Нельзя садиться за руль пьяным.","vi":"Bạn không nên lái xe khi say rượu.","fa":"شما نباید در حالت مستی رانندگی کنید."}]},{"word":"das Bett","en":"bed","ru":"кровать","vi":"cái giường","fa":"تخت","examples":[{"de":"Ich gehe früh ins Bett.","en":"I go to bed early.","ru":"Я рано ложусь спать.","vi":"Tôi đi ngủ sớm.","fa":"زود به رختخواب می روم."},{"de":"Das Bett im Hotelzimmer war sehr bequem.","en":"The bed in the hotel room was very comfortable.","ru":"Кровать в номере отеля была очень удобной.","vi":"Chiếc giường trong phòng khách sạn rất thoải mái.","fa":"تخت در اتاق هتل بسیار راحت بود."}]},{"word":"beugen","en":"to bend","ru":"сгибать, наклонять","vi":"uốn cong","fa":"خم شدن","examples":[{"de":"Beuge dich langsam nach vorne und berühre den Boden.","en":"Bend forward slowly and touch the floor.","ru":"Медленно наклонись вперёд и коснись пола.","vi":"Từ từ cúi người về phía trước và chạm sàn.","fa":"به آرامی به جلو خم شوید و کف را لمس کنید."},{"de":"Beim Einatmen beugst du dich leicht nach hinten.","en":"As you breathe in you bend slightly backwards.","ru":"На вдохе ты слегка прогибаешься назад.","vi":"Khi hít vào, hơi cúi người về phía sau.","fa":"در حین نفس کشیدن، کمی به سمت عقب خم شوید."},{"de":"Beuge die Knie, damit der Rücken gerade bleibt.","en":"Bend your knees so that your back stays straight.","ru":"Согни колени, чтобы спина оставалась прямой.","vi":"Cong đầu gối của bạn để giữ cho lưng thẳng.","fa":"زانوهایتان را خم کنید تا کمرتان صاف بماند."}]},{"word":"die Bevölkerung","en":"population","ru":"население","vi":"dân số","fa":"جمعیت","examples":[{"de":"Die Bevölkerung der Stadt wächst schnell.","en":"The population of the city is growing fast.","ru":"Население города быстро растёт.","vi":"Dân số thành phố đang tăng nhanh.","fa":"جمعیت این شهر به سرعت در حال افزایش است."},{"de":"Ein großer Teil der Bevölkerung lebt auf dem Land.","en":"A large part of the population lives in the countryside.","ru":"Значительная часть населения живёт в сельской местности.","vi":"Một bộ phận lớn dân số sống ở khu vực nông thôn.","fa":"بخش بزرگی از جمعیت در مناطق روستایی زندگی می کنند."}]},{"word":"bevor","en":"before","ru":"прежде чем, до того как","vi":"trước đây","fa":"قبل از","examples":[{"de":"Bevor du gehst, schalte bitte das Licht aus.","en":"Before you leave, please turn off the light.","ru":"Прежде чем уйти, выключи, пожалуйста, свет.","vi":"Trước khi rời đi, vui lòng tắt đèn.","fa":"قبل از رفتن لطفا چراغ ها را خاموش کنید."},{"de":"Wir müssen einkaufen, bevor die Geschäfte schließen.","en":"We have to go shopping before the shops close.","ru":"Нам нужно сходить за покупками, прежде чем магазины закроются.","vi":"Chúng ta phải mua sắm trước khi các cửa hàng đóng cửa.","fa":"ما باید قبل از بسته شدن مغازه ها خرید کنیم."}]},{"word":"bewegen","en":"to move","ru":"двигать(ся)","vi":"di chuyển","fa":"حرکت کنید","examples":[{"de":"Er kann seinen Arm nach der Operation kaum bewegen.","en":"He can barely move his arm after the operation.","ru":"Он едва может двигать рукой после операции.","vi":"Anh ấy hầu như không thể cử động cánh tay của mình sau ca phẫu thuật.","fa":"او پس از عمل به سختی می تواند بازوی خود را حرکت دهد."},{"de":"Das Kind bewegt sich sehr geschickt beim Tanzen.","en":"The child moves very skillfully while dancing.","ru":"Ребёнок очень ловко двигается во время танца.","vi":"Đứa trẻ di chuyển rất khéo léo trong khi nhảy.","fa":"کودک هنگام رقصیدن بسیار ماهرانه حرکت می کند."}]},{"word":"beweglich","en":"supple, flexible","ru":"гибкий, подвижный","vi":"có thể di chuyển được","fa":"متحرک","examples":[{"de":"Durch Yoga bin ich viel beweglicher geworden.","en":"Through yoga I have become much more supple.","ru":"Благодаря йоге я стал намного гибче.","vi":"Yoga đã khiến tôi linh hoạt hơn rất nhiều.","fa":"یوگا من را بسیار انعطاف پذیرتر کرده است."},{"de":"Kinder sind von Natur aus sehr beweglich.","en":"Children are naturally very flexible.","ru":"Дети от природы очень гибкие.","vi":"Trẻ em tự nhiên rất năng động.","fa":"کودکان به طور طبیعی بسیار متحرک هستند."},{"de":"Meine Schultern sind morgens weniger beweglich.","en":"My shoulders are less flexible in the morning.","ru":"По утрам мои плечи менее подвижны.","vi":"Vai của tôi ít di động hơn vào buổi sáng.","fa":"شانه هایم صبح ها کمتر تحرک دارند."}]},{"word":"die Beweglichkeit","en":"flexibility, mobility","ru":"гибкость, подвижность","vi":"sự di chuyển","fa":"تحرک","examples":[{"de":"Regelmäßiges Yoga verbessert die Beweglichkeit.","en":"Regular yoga improves flexibility.","ru":"Регулярная йога улучшает гибкость.","vi":"Tập yoga thường xuyên giúp cải thiện tính linh hoạt.","fa":"یوگای منظم انعطاف پذیری را بهبود می بخشد."},{"de":"Meine Beweglichkeit ist im Laufe der Monate gewachsen.","en":"My flexibility has grown over the months.","ru":"Моя гибкость выросла за эти месяцы.","vi":"Khả năng di chuyển của tôi đã tăng lên trong những tháng qua.","fa":"تحرک من در طول ماه ها افزایش یافته است."},{"de":"Für diese Stellung braucht man viel Beweglichkeit.","en":"This pose requires a lot of flexibility.","ru":"Для этой позы требуется большая гибкость.","vi":"Vị trí này đòi hỏi rất nhiều sự linh hoạt.","fa":"این موقعیت به انعطاف پذیری زیادی نیاز دارد."}]},{"word":"die Beweglichkeit fördern","en":"to improve flexibility","ru":"развивать гибкость (подвижность)","vi":"thúc đẩy tính di động","fa":"ترویج تحرک","examples":[{"de":"Yoga kann die Beweglichkeit der Gelenke fördern.","en":"Yoga can improve the flexibility of the joints.","ru":"Йога может развивать гибкость суставов.","vi":"Yoga có thể thúc đẩy khả năng vận động của khớp.","fa":"یوگا می تواند تحرک مفاصل را تقویت کند."},{"de":"Diese Übung fördert besonders die Beweglichkeit des Rückens.","en":"This exercise especially improves the flexibility of the back.","ru":"Это упражнение особенно развивает гибкость спины.","vi":"Bài tập này đặc biệt thúc đẩy khả năng vận động của lưng.","fa":"این تمرین به ویژه تحرک کمر را تقویت می کند."},{"de":"Regelmäßiges Dehnen fördert die Beweglichkeit.","en":"Regular stretching improves flexibility.","ru":"Регулярная растяжка развивает гибкость.","vi":"Kéo dài thường xuyên thúc đẩy khả năng vận động.","fa":"کشش منظم باعث افزایش تحرک می شود."}]},{"word":"beweisen","en":"to prove","ru":"доказывать","vi":"chứng minh","fa":"ثابت کند","examples":[{"de":"Er konnte seine Unschuld beweisen.","en":"He was able to prove his innocence.","ru":"Он смог доказать свою невиновность.","vi":"Anh ta đã có thể chứng minh sự vô tội của mình.","fa":"او توانست بی گناهی خود را ثابت کند."},{"de":"Diese Ergebnisse beweisen, dass die Methode funktioniert.","en":"These results prove that the method works.","ru":"Эти результаты доказывают, что метод работает.","vi":"Những kết quả này chứng minh rằng phương pháp này hoạt động.","fa":"این نتایج ثابت می کند که روش کار می کند."}]},{"word":"die Bewerbung","en":"application (for a job)","ru":"заявление о приёме на работу","vi":"ứng dụng","fa":"برنامه","examples":[{"de":"Ich habe meine Bewerbung gestern abgeschickt.","en":"I sent off my application yesterday.","ru":"Я отправил своё заявление вчера.","vi":"Tôi đã gửi đơn đăng ký của mình ngày hôm qua.","fa":"من دیروز درخواستم رو فرستادم"},{"de":"Zur Bewerbung gehören ein Anschreiben und ein Lebenslauf.","en":"An application includes a cover letter and a CV.","ru":"Заявление включает сопроводительное письмо и резюме.","vi":"Hồ sơ bao gồm thư xin việc và CV.","fa":"این برنامه شامل یک جلد نامه و یک CV است."}]},{"word":"die Bewerbung schreiben","en":"to write a job application","ru":"написать заявку на работу (сопроводительное письмо)","vi":"viết ứng dụng","fa":"برنامه را بنویسید","examples":[{"de":"Am Wochenende will ich meine Bewerbung schreiben.","en":"At the weekend I want to write my job application.","ru":"На выходных я хочу написать заявку на работу.","vi":"Tôi muốn viết đơn đăng ký vào cuối tuần này.","fa":"من می خواهم این آخر هفته درخواست خود را بنویسم."},{"de":"Eine gute Bewerbung schreiben ist gar nicht so leicht.","en":"Writing a good job application is not that easy.","ru":"Написать хорошую заявку на работу совсем не просто.","vi":"Viết một ứng dụng tốt không phải là điều dễ dàng.","fa":"نوشتن یک برنامه خوب به این راحتی نیست."},{"de":"Sie hat schon zwanzig Bewerbungen geschrieben.","en":"She has already written twenty applications.","ru":"Она уже написала двадцать заявок.","vi":"Cô ấy đã viết được 20 đơn xin việc.","fa":"او در حال حاضر بیست درخواست نوشته است."}]},{"word":"bewerten","en":"to evaluate; to rate; to grade","ru":"оценивать","vi":"đánh giá","fa":"ارزیابی کنید","examples":[{"de":"Der Lehrer bewertet die Aufsätze am Wochenende.","en":"The teacher grades the essays at the weekend.","ru":"Учитель оценивает сочинения на выходных.","vi":"Giáo viên chấm bài vào cuối tuần.","fa":"معلم انشاها را در آخر هفته نمره می دهد."},{"de":"Wie würdest du diesen Film bewerten?","en":"How would you rate this film?","ru":"Как бы ты оценил этот фильм?","vi":"Bạn đánh giá bộ phim này như thế nào?","fa":"به این فیلم چه امتیازی می دهید؟"}]},{"word":"die Bewertung","en":"assessment, rating, review","ru":"оценка, отзыв","vi":"sự đánh giá","fa":"ارزیابی","examples":[{"de":"Vor dem Kauf lese ich immer die Bewertungen anderer Kunden.","en":"Before buying I always read other customers' reviews.","ru":"Перед покупкой я всегда читаю отзывы других покупателей.","vi":"Trước khi mua, tôi luôn đọc đánh giá của khách hàng khác.","fa":"قبل از خرید، من همیشه نظرات سایر مشتریان را می خوانم."},{"de":"Die Bewertung der Prüfung dauert etwa zwei Wochen.","en":"The assessment of the exam takes about two weeks.","ru":"Проверка и оценка экзамена длится около двух недель.","vi":"Việc chấm điểm bài kiểm tra mất khoảng hai tuần.","fa":"نمره دادن به امتحان تقریباً دو هفته طول می کشد."},{"de":"Das Restaurant hat eine sehr gute Bewertung im Internet.","en":"The restaurant has a very good rating on the internet.","ru":"У ресторана очень хороший рейтинг в интернете.","vi":"Nhà hàng được đánh giá rất tốt trên mạng.","fa":"این رستوران امتیاز آنلاین بسیار خوبی دارد."}]},{"word":"der Bewohner","en":"resident, inhabitant","ru":"житель","vi":"cư dân","fa":"ساکن","examples":[{"de":"Die Bewohner des Hauses beschwerten sich über den Lärm.","en":"The residents of the building complained about the noise.","ru":"Жители дома пожаловались на шум.","vi":"Người dân trong nhà phàn nàn về tiếng ồn.","fa":"اهالی خانه از سر و صدا شکایت کردند."},{"de":"Alle Bewohner der Insel kennen sich.","en":"All the inhabitants of the island know each other.","ru":"Все жители острова знают друг друга.","vi":"Mọi người trên đảo đều biết nhau.","fa":"همه در جزیره یکدیگر را می شناسند."}]},{"word":"die Bewohnerin","en":"resident, inhabitant (female)","ru":"жительница, жилица","vi":"cư dân","fa":"ساکن","examples":[{"de":"Die Bewohnerin der Wohnung über uns ist sehr nett.","en":"The resident of the flat above us is very nice.","ru":"Жительница квартиры над нами очень милая.","vi":"Cư dân của căn hộ phía trên chúng tôi rất tốt bụng.","fa":"ساکن آپارتمان بالای ما بسیار خوب است."},{"de":"Eine Bewohnerin des Hauses hat den Notruf gewählt.","en":"A resident of the building dialled the emergency number.","ru":"Одна из жительниц дома вызвала экстренную службу.","vi":"Một cư dân trong ngôi nhà đã gọi 911.","fa":"یکی از ساکنان خانه با شماره 911 تماس گرفت."},{"de":"Als langjährige Bewohnerin kennt sie das Viertel gut.","en":"As a long-time resident she knows the neighbourhood well.","ru":"Как давняя жительница она хорошо знает квартал.","vi":"Là người sống lâu năm nên cô biết rõ khu vực này.","fa":"او به عنوان یک ساکن قدیمی، محله را به خوبی می شناسد."}]},{"word":"bewölkt","en":"cloudy, overcast","ru":"облачный, пасмурный","vi":"nhiều mây","fa":"ابری","examples":[{"de":"Der Himmel ist heute den ganzen Tag bewölkt.","en":"The sky is overcast all day today.","ru":"Небо сегодня весь день пасмурное.","vi":"Hôm nay trời nhiều mây cả ngày.","fa":"آسمان امروز تمام روز ابری است."},{"de":"Morgen wird es bewölkt, aber es bleibt trocken.","en":"Tomorrow it will be cloudy, but it will stay dry.","ru":"Завтра будет облачно, но останется сухо.","vi":"Ngày mai trời sẽ nhiều mây nhưng vẫn khô ráo.","fa":"فردا هوا ابری است اما خشک خواهد ماند."},{"de":"Bei bewölktem Wetter sieht man die Berge kaum.","en":"In cloudy weather you can hardly see the mountains.","ru":"В пасмурную погоду гор почти не видно.","vi":"Trong thời tiết nhiều mây, bạn khó có thể nhìn thấy những ngọn núi.","fa":"در هوای ابری به سختی می توانید کوه ها را ببینید."}]},{"word":"das Bewusstsein","en":"awareness, consciousness","ru":"осознание, сознательность","vi":"ý thức","fa":"آگاهی","examples":[{"de":"Das Bewusstsein für den Umweltschutz ist gewachsen.","en":"Awareness of environmental protection has grown.","ru":"Осознание важности защиты окружающей среды выросло.","vi":"Ý thức bảo vệ môi trường ngày càng được nâng cao.","fa":"آگاهی از حفاظت از محیط زیست افزایش یافته است."},{"de":"Viele junge Leute haben ein starkes ökologisches Bewusstsein.","en":"Many young people have a strong ecological awareness.","ru":"У многих молодых людей сильное экологическое сознание.","vi":"Nhiều bạn trẻ có ý thức sinh thái mạnh mẽ.","fa":"بسیاری از جوانان آگاهی زیست محیطی قوی دارند."},{"de":"Schulen wollen das Bewusstsein für Nachhaltigkeit fördern.","en":"Schools want to promote awareness of sustainability.","ru":"Школы хотят развивать осознание устойчивого развития.","vi":"Các trường học muốn nâng cao nhận thức về tính bền vững.","fa":"مدارس می خواهند آگاهی از پایداری را ارتقا دهند."}]},{"word":"bezahlen","en":"to pay","ru":"платить","vi":"trả tiền","fa":"پرداخت کنید","examples":[{"de":"Wer bezahlt die Rechnung?","en":"Who is paying the bill?","ru":"Кто платит по счёту?","vi":"Ai thanh toán hóa đơn?","fa":"چه کسی قبض را پرداخت می کند؟"},{"de":"Ich habe die Miete schon bezahlt.","en":"I have already paid the rent.","ru":"Я уже заплатил за квартиру.","vi":"Tôi đã trả tiền thuê nhà rồi.","fa":"من قبلاً اجاره را پرداخت کرده ام."}]},{"word":"die Beziehung","en":"relationship","ru":"отношения, связь","vi":"mối quan hệ","fa":"رابطه","examples":[{"de":"Sie haben eine glückliche Beziehung.","en":"They have a happy relationship.","ru":"У них счастливые отношения.","vi":"Họ có một mối quan hệ hạnh phúc.","fa":"آنها رابطه شادی دارند."},{"de":"Die Beziehung zwischen den beiden Ländern hat sich verbessert.","en":"The relationship between the two countries has improved.","ru":"Отношения между двумя странами улучшились.","vi":"Mối quan hệ giữa hai nước đã được cải thiện.","fa":"روابط بین دو کشور بهبود یافته است."}]},{"word":"beziehungsweise","en":"or rather; respectively","ru":"или; точнее; соответственно","vi":"tương ứng","fa":"به ترتیب","examples":[{"de":"Wir treffen uns am Montag beziehungsweise Dienstag.","en":"We'll meet on Monday or rather Tuesday.","ru":"Мы встретимся в понедельник, точнее, во вторник.","vi":"Chúng tôi gặp nhau vào thứ Hai hoặc thứ Ba.","fa":"دوشنبه یا سه شنبه همدیگر را می بینیم."},{"de":"Die Männer und Frauen gingen in den linken beziehungsweise rechten Raum.","en":"The men and women went into the left and right room respectively.","ru":"Мужчины и женщины пошли в левую и правую комнаты соответственно.","vi":"Nam và nữ lần lượt đi vào phòng bên trái và bên phải.","fa":"مردان و زنان به ترتیب به اتاق چپ و راست رفتند."}]},{"word":"die Bibliothek","en":"library","ru":"библиотека","vi":"thư viện","fa":"کتابخانه","examples":[{"de":"Ich leihe mir Bücher aus der Bibliothek aus.","en":"I borrow books from the library.","ru":"Я беру книги в библиотеке.","vi":"Tôi mượn sách từ thư viện.","fa":"از کتابخانه کتاب امانت می‌گیرم."},{"de":"Die Universität hat eine große Bibliothek.","en":"The university has a large library.","ru":"В университете большая библиотека.","vi":"Trường đại học có một thư viện lớn.","fa":"این دانشگاه یک کتابخانه بزرگ دارد."}]},{"word":"das Bier","en":"beer","ru":"пиво","vi":"bia","fa":"آبجو","examples":[{"de":"Er trinkt gern ein kühles Bier nach der Arbeit.","en":"He likes to drink a cold beer after work.","ru":"Он любит выпить холодного пива после работы.","vi":"Anh ấy thích uống bia lạnh sau giờ làm việc.","fa":"او دوست دارد بعد از کار یک آبجو سرد بنوشد."},{"de":"In Deutschland gibt es viele verschiedene Biersorten.","en":"In Germany there are many different types of beer.","ru":"В Германии много разных сортов пива.","vi":"Có rất nhiều loại bia khác nhau ở Đức.","fa":"انواع مختلفی از آبجو در آلمان وجود دارد."}]},{"word":"bieten","en":"to offer","ru":"предлагать","vi":"đề nghị","fa":"پیشنهاد","examples":[{"de":"Das Hotel bietet einen tollen Service.","en":"The hotel offers great service.","ru":"Отель предлагает отличный сервис.","vi":"Khách sạn cung cấp dịch vụ tuyệt vời.","fa":"این هتل خدمات عالی ارائه می دهد."},{"de":"Die Firma bietet ihren Mitarbeitern flexible Arbeitszeiten.","en":"The company offers its employees flexible working hours.","ru":"Компания предлагает своим сотрудникам гибкий график работы.","vi":"Công ty cung cấp cho nhân viên thời gian làm việc linh hoạt.","fa":"این شرکت ساعات کاری انعطاف پذیری را به کارکنان خود ارائه می دهد."}]},{"word":"der Bikini","en":"bikini","ru":"бикини","vi":"bộ bikini","fa":"بیکینی","examples":[{"de":"Im Sommer trage ich am Strand am liebsten einen Bikini.","en":"In summer I like to wear a bikini on the beach the most.","ru":"Летом на пляже я больше всего люблю носить бикини.","vi":"Vào mùa hè, tôi thích mặc bikini trên bãi biển hơn.","fa":"در تابستان ترجیح می دهم در ساحل بیکینی بپوشم."},{"de":"Sie hat sich einen neuen Bikini für den Urlaub gekauft.","en":"She bought a new bikini for the holiday.","ru":"Она купила себе новое бикини для отпуска.","vi":"Cô ấy mua một bộ bikini mới để đi nghỉ.","fa":"او یک بیکینی جدید برای تعطیلات خرید."},{"de":"Der rote Bikini steht ihr wirklich gut.","en":"The red bikini really suits her.","ru":"Красное бикини ей очень идёт.","vi":"Bộ bikini màu đỏ thực sự rất hợp với cô ấy.","fa":"بیکینی قرمز واقعا به او می آید."}]},{"word":"das Bild","en":"picture, image","ru":"картина, изображение","vi":"bức tranh","fa":"تصویر","examples":[{"de":"An der Wand hängt ein schönes Bild.","en":"A beautiful picture hangs on the wall.","ru":"На стене висит красивая картина.","vi":"Có một bức tranh đẹp treo trên tường.","fa":"یک عکس زیبا روی دیوار آویزان شده است."},{"de":"Kannst du mir ein Bild von deiner Reise zeigen?","en":"Can you show me a picture from your trip?","ru":"Можешь показать мне фотографию из своей поездки?","vi":"Bạn có thể cho tôi xem một bức ảnh từ chuyến đi của bạn được không?","fa":"میشه یه عکس از سفرت بهم نشون بدی؟"}]},{"word":"der Bildschirm","en":"screen; monitor","ru":"экран","vi":"màn hình","fa":"صفحه نمایش","examples":[{"de":"Der Bildschirm meines Laptops ist sehr groß.","en":"My laptop's screen is very big.","ru":"Экран моего ноутбука очень большой.","vi":"Màn hình máy tính xách tay của tôi rất lớn.","fa":"صفحه لپ تاپ من خیلی بزرگه"},{"de":"Bitte schau nicht die ganze Zeit auf den Bildschirm.","en":"Please don't look at the screen the whole time.","ru":"Пожалуйста, не смотри всё время на экран.","vi":"Làm ơn đừng nhìn vào màn hình mọi lúc.","fa":"لطفا همیشه به صفحه نمایش نگاه نکنید."}]},{"word":"die Bildung","en":"education","ru":"образование","vi":"giáo dục","fa":"آموزش و پرورش","examples":[{"de":"Bildung ist der Schlüssel zu einer besseren Zukunft.","en":"Education is the key to a better future.","ru":"Образование — ключ к лучшему будущему.","vi":"Giáo dục là chìa khóa cho một tương lai tốt đẹp hơn.","fa":"آموزش کلید آینده بهتر است."},{"de":"Der Staat investiert zu wenig in die Bildung.","en":"The state invests too little in education.","ru":"Государство слишком мало вкладывает в образование.","vi":"Nhà nước đầu tư quá ít vào giáo dục.","fa":"دولت خیلی کم در آموزش سرمایه گذاری می کند."}]},{"word":"das Billet","en":"ticket (Swiss German)","ru":"билет (швейцарский вариант)","vi":"vé","fa":"بلیط","examples":[{"de":"In der Schweiz kaufst du am Automaten ein Billet für den Zug.","en":"In Switzerland you buy a ticket for the train at the machine.","ru":"В Швейцарии билет на поезд ты покупаешь в автомате.","vi":"Ở Thụy Sĩ, bạn mua vé tàu từ máy.","fa":"در سوئیس بلیط قطار را از ماشین می‌خرید."},{"de":"Ich habe mein Billet für die Fahrt nach Zürich gelöst.","en":"I bought my ticket for the journey to Zurich.","ru":"Я купил билет на поездку в Цюрих.","vi":"Tôi đã mua vé cho chuyến đi tới Zurich.","fa":"بلیط سفر زوریخ را خریدم."},{"de":"Bitte zeigen Sie Ihr Billet dem Kontrolleur.","en":"Please show your ticket to the conductor.","ru":"Пожалуйста, покажите билет контролёру.","vi":"Vui lòng xuất trình vé của bạn cho thanh tra.","fa":"لطفا بلیط خود را به بازرس نشان دهید."}]},{"word":"das Billett","en":"ticket","ru":"билет","vi":"vé","fa":"بلیط","examples":[{"de":"Ich kaufe ein Billett für den Zug nach Zürich.","en":"I buy a ticket for the train to Zurich.","ru":"Я покупаю билет на поезд в Цюрих.","vi":"Tôi mua vé tàu đi Zurich.","fa":"بلیت قطار زوریخ می خرم."},{"de":"Hast du dein Billett schon am Automaten geholt?","en":"Have you already gotten your ticket from the machine?","ru":"Ты уже взял свой билет в автомате?","vi":"Bạn đã nhận được vé từ máy chưa?","fa":"آیا قبلا بلیط خود را از دستگاه دریافت کرده اید؟"}]},{"word":"billig","en":"cheap","ru":"дешёвый","vi":"giá rẻ","fa":"ارزان","examples":[{"de":"Dieses Restaurant ist sehr billig.","en":"This restaurant is very cheap.","ru":"Этот ресторан очень дешёвый.","vi":"Nhà hàng này rất rẻ.","fa":"این رستوران بسیار ارزان است."},{"de":"Ich suche ein billiges Hotel in der Stadt.","en":"I'm looking for a cheap hotel in the city.","ru":"Я ищу дешёвую гостиницу в городе.","vi":"Tôi đang tìm một khách sạn giá rẻ ở thành phố.","fa":"من به دنبال یک هتل ارزان در شهر هستم."}]},{"word":"bio","en":"organic (food)","ru":"экологический, био- (о продуктах)","vi":"sinh học","fa":"زیستی","examples":[{"de":"Diese Eier sind bio und kommen vom Bauernhof.","en":"These eggs are organic and come from the farm.","ru":"Эти яйца экологические и с фермы.","vi":"Những quả trứng này là hữu cơ và đến từ trang trại.","fa":"این تخم ها ارگانیک هستند و از مزرعه می آیند."},{"de":"Ich kaufe meine Milch immer bio.","en":"I always buy my milk organic.","ru":"Я всегда покупаю био-молоко.","vi":"Tôi luôn mua sữa hữu cơ của mình.","fa":"من همیشه شیرم را ارگانیک می خرم."},{"de":"Im Supermarkt gibt es jetzt viele Bio-Produkte.","en":"In the supermarket there are now many organic products.","ru":"В супермаркете теперь много биопродуктов.","vi":"Hiện nay có rất nhiều sản phẩm hữu cơ trong siêu thị.","fa":"در حال حاضر بسیاری از محصولات ارگانیک در سوپرمارکت وجود دارد."}]},{"word":"bio-","en":"organic, bio- (prefix)","ru":"эко-, био- (приставка)","vi":"hữu cơ","fa":"ارگانیک","examples":[{"de":"Im Laden gibt es viele Bio-Lebensmittel.","en":"In the shop there are many organic foods.","ru":"В магазине много экологических продуктов.","vi":"Có rất nhiều thực phẩm hữu cơ trong cửa hàng.","fa":"غذاهای ارگانیک زیادی در فروشگاه وجود دارد."},{"de":"Bio-Bauern verzichten auf chemische Düngemittel.","en":"Organic farmers do without chemical fertilisers.","ru":"Эко-фермеры обходятся без химических удобрений.","vi":"Nông dân hữu cơ tránh phân bón hóa học.","fa":"کشاورزان ارگانیک از کودهای شیمیایی اجتناب می کنند."},{"de":"Wir kaufen oft Bio-Obst auf dem Markt.","en":"We often buy organic fruit at the market.","ru":"Мы часто покупаем на рынке био-фрукты.","vi":"Chúng tôi thường mua trái cây hữu cơ ở chợ.","fa":"ما اغلب میوه های ارگانیک را از بازار می خریم."}]},{"word":"die Biologie","en":"biology","ru":"биология","vi":"sinh học","fa":"زیست شناسی","examples":[{"de":"In der Schule hatten wir heute Biologie.","en":"We had biology at school today.","ru":"Сегодня в школе у нас была биология.","vi":"Ở trường hôm nay chúng tôi học môn sinh học.","fa":"امروز در مدرسه زیست شناسی داشتیم."},{"de":"Sie studiert Biologie an der Universität.","en":"She studies biology at university.","ru":"Она изучает биологию в университете.","vi":"Cô ấy nghiên cứu sinh học ở trường đại học.","fa":"او در دانشگاه زیست شناسی می خواند."}]},{"word":"biologisch","en":"biological; organic","ru":"биологический; экологический","vi":"sinh học","fa":"بیولوژیکی","examples":[{"de":"Diese Lebensmittel stammen aus biologischem Anbau.","en":"These foods come from organic cultivation.","ru":"Эти продукты — из экологического хозяйства.","vi":"Những thực phẩm này đến từ canh tác hữu cơ.","fa":"این غذاها از کشاورزی ارگانیک به دست می آیند."},{"de":"Der biologische Unterschied zwischen den Arten ist groß.","en":"The biological difference between the species is large.","ru":"Биологическое различие между видами велико.","vi":"Sự khác biệt sinh học giữa các loài là lớn.","fa":"تفاوت بیولوژیکی بین گونه ها زیاد است."},{"de":"Die Verpackung ist biologisch abbaubar.","en":"The packaging is biologically degradable.","ru":"Упаковка биологически разлагаемая.","vi":"Bao bì có khả năng phân hủy sinh học.","fa":"بسته بندی زیست تخریب پذیر است."}]},{"word":"der Biomüll","en":"organic/food waste, bio-waste","ru":"биоотходы, пищевые отходы","vi":"chất thải hữu cơ","fa":"زباله های ارگانیک","examples":[{"de":"Essensreste kommen bei uns in den Biomüll.","en":"Food scraps go in our bio-waste bin.","ru":"Остатки еды у нас идут в биоотходы.","vi":"Thức ăn thừa sẽ được chuyển vào chất thải hữu cơ.","fa":"غذای باقیمانده به زباله های آلی می رود."},{"de":"Aus Biomüll kann man guten Kompost machen.","en":"You can make good compost out of bio-waste.","ru":"Из биоотходов можно сделать хороший компост.","vi":"Bạn có thể làm phân trộn tốt từ rác hữu cơ.","fa":"می توانید از زباله های آلی کمپوست خوبی بسازید."},{"de":"Die braune Tonne ist für den Biomüll.","en":"The brown bin is for bio-waste.","ru":"Коричневый бак — для биоотходов.","vi":"Thùng màu nâu dùng để đựng rác hữu cơ.","fa":"سطل قهوه ای مخصوص زباله های آلی است."}]},{"word":"das Bioprodukt","en":"organic product","ru":"экологический (био-) продукт","vi":"sản phẩm hữu cơ","fa":"محصول ارگانیک","examples":[{"de":"Im Supermarkt gibt es immer mehr Bioprodukte.","en":"There are more and more organic products in the supermarket.","ru":"В супермаркете всё больше биопродуктов.","vi":"Ngày càng có nhiều sản phẩm hữu cơ trong siêu thị.","fa":"محصولات ارگانیک بیشتر و بیشتر در سوپرمارکت وجود دارد."},{"de":"Bioprodukte sind oft teurer als normale Lebensmittel.","en":"Organic products are often more expensive than ordinary food.","ru":"Биопродукты часто дороже обычных продуктов.","vi":"Các sản phẩm hữu cơ thường đắt hơn thực phẩm thông thường.","fa":"محصولات ارگانیک اغلب گرانتر از مواد غذایی معمولی هستند."},{"de":"Sie kauft am liebsten Bioprodukte aus der Region.","en":"She prefers to buy organic products from the region.","ru":"Она больше всего любит покупать биопродукты из своего региона.","vi":"Cô thích mua các sản phẩm hữu cơ trong vùng hơn.","fa":"او ترجیح می دهد محصولات ارگانیک را از منطقه خریداری کند."}]},{"word":"die Birne","en":"pear; light bulb","ru":"груша; лампочка","vi":"quả lê","fa":"گلابی","examples":[{"de":"Ich esse gern eine süße Birne zum Frühstück.","en":"I like eating a sweet pear for breakfast.","ru":"Я люблю есть сладкую грушу на завтрак.","vi":"Tôi thích ăn một quả lê ngọt vào bữa sáng.","fa":"من دوست دارم برای صبحانه یک گلابی شیرین بخورم."},{"de":"Die Birne in der Küche ist kaputt, wir brauchen eine neue.","en":"The light bulb in the kitchen is broken, we need a new one.","ru":"Лампочка на кухне перегорела, нам нужна новая.","vi":"Bóng đèn trong bếp hỏng rồi, chúng ta cần một cái mới.","fa":"لامپ آشپزخانه خراب است، به یک لامپ جدید نیاز داریم."}]},{"word":"bis","en":"until; by","ru":"до","vi":"cho đến khi","fa":"تا","examples":[{"de":"Ich bleibe bis Freitag bei meinen Eltern.","en":"I'm staying at my parents' until Friday.","ru":"Я останусь у родителей до пятницы.","vi":"Tôi sẽ ở với bố mẹ cho đến thứ Sáu.","fa":"من تا جمعه پیش پدر و مادرم می مانم."},{"de":"Der Laden hat bis 20 Uhr geöffnet.","en":"The shop is open until 8 pm.","ru":"Магазин открыт до 20 часов.","vi":"Cửa hàng mở cửa đến 8 giờ tối.","fa":"فروشگاه تا ساعت 8 شب باز است."}]},{"word":"bisher","en":"so far; up to now","ru":"до сих пор","vi":"cho đến nay","fa":"تا کنون","examples":[{"de":"Bisher habe ich keine Antwort auf meine E-Mail bekommen.","en":"So far I haven't received an answer to my email.","ru":"До сих пор я не получил ответа на своё письмо.","vi":"Cho đến nay tôi vẫn chưa nhận được phản hồi cho email của mình.","fa":"تاکنون پاسخی به ایمیلم دریافت نکرده ام."},{"de":"Bisher war das Wetter im Urlaub sehr schön.","en":"So far the weather has been very nice on vacation.","ru":"До сих пор погода в отпуске была очень хорошей.","vi":"Cho đến nay thời tiết trong kỳ nghỉ rất đẹp.","fa":"تا الان در تعطیلات هوا خیلی خوب بوده است."}]},{"word":"bitten","en":"to ask; to request","ru":"просить","vi":"hỏi","fa":"بپرسید","examples":[{"de":"Ich möchte dich um einen Gefallen bitten.","en":"I'd like to ask you for a favor.","ru":"Я хотел бы попросить тебя об услуге.","vi":"Tôi muốn nhờ bạn một việc.","fa":"من می خواهم از شما یک لطفی بخواهم."},{"de":"Er bittet den Lehrer um mehr Zeit für die Prüfung.","en":"He asks the teacher for more time for the exam.","ru":"Он просит учителя дать больше времени на экзамен.","vi":"Anh ấy xin giáo viên cho thêm thời gian cho kỳ thi.","fa":"از معلم وقت بیشتری برای امتحان می خواهد."}]},{"word":"bitter","en":"bitter","ru":"горький","vi":"cay đắng","fa":"تلخ","examples":[{"de":"Der Kaffee ohne Zucker schmeckt sehr bitter.","en":"Coffee without sugar tastes very bitter.","ru":"Кофе без сахара очень горький на вкус.","vi":"Cà phê không đường có vị rất đắng.","fa":"قهوه بدون شکر طعم بسیار تلخی دارد."},{"de":"Diese Medizin ist sehr bitter.","en":"This medicine is very bitter.","ru":"Это лекарство очень горькое.","vi":"Thuốc này rất đắng.","fa":"این دارو بسیار تلخ است."}]},{"word":"blass","en":"pale","ru":"бледный","vi":"nhợt nhạt","fa":"رنگ پریده","examples":[{"de":"Du siehst heute sehr blass aus, geht es dir gut?","en":"You look very pale today, are you okay?","ru":"Ты сегодня выглядишь очень бледным, у тебя всё хорошо?","vi":"Hôm nay trông bạn xanh xao lắm, bạn ổn chứ?","fa":"امروز خیلی رنگ پریده به نظر می رسید، خوب هستید؟"},{"de":"Nach der Krankheit war ihr Gesicht blass.","en":"After the illness her face was pale.","ru":"После болезни её лицо было бледным.","vi":"Sau cơn bệnh, sắc mặt bà tái nhợt.","fa":"بعد از بیماری، صورتش رنگ پریده بود."}]},{"word":"das Blatt","en":"leaf; sheet of paper","ru":"лист","vi":"tờ giấy","fa":"ورق","examples":[{"de":"Im Herbst fallen die Blätter von den Bäumen.","en":"In autumn the leaves fall from the trees.","ru":"Осенью листья падают с деревьев.","vi":"Vào mùa thu, lá rụng khỏi cây.","fa":"در پاییز برگها از درختان می ریزند."},{"de":"Gib mir bitte ein Blatt Papier.","en":"Please give me a sheet of paper.","ru":"Дай мне, пожалуйста, лист бумаги.","vi":"Xin vui lòng cho tôi một mảnh giấy.","fa":"لطفا یک تکه کاغذ به من بدهید."}]},{"word":"bleiben","en":"to stay; to remain","ru":"оставаться","vi":"ở lại","fa":"ماندن","examples":[{"de":"Ich möchte heute Abend zu Hause bleiben.","en":"I want to stay home tonight.","ru":"Я хочу остаться сегодня вечером дома.","vi":"Tôi muốn ở nhà tối nay.","fa":"میخوام امشب خونه بمونم"},{"de":"Bleib bitte ruhig, es ist nichts Schlimmes passiert.","en":"Please stay calm, nothing bad has happened.","ru":"Пожалуйста, оставайся спокойным, ничего плохого не случилось.","vi":"Xin hãy bình tĩnh, không có chuyện gì xấu xảy ra cả.","fa":"لطفا آرام باشید، اتفاق بدی نیفتاده است."}]},{"word":"der Bleistift","en":"pencil","ru":"карандаш","vi":"cây bút chì","fa":"مداد","examples":[{"de":"Hast du einen Bleistift für die Mathe-Hausaufgaben?","en":"Do you have a pencil for the math homework?","ru":"У тебя есть карандаш для домашнего задания по математике?","vi":"Bạn có bút chì để làm bài tập toán không?","fa":"آیا برای تکالیف ریاضی خود مداد دارید؟"},{"de":"Der Bleistift ist abgebrochen, ich brauche einen Spitzer.","en":"The pencil broke, I need a sharpener.","ru":"Карандаш сломался, мне нужна точилка.","vi":"Bút chì bị gãy, tôi cần một cái gọt.","fa":"مداد شکست، من نیاز به تراش دارم."}]},{"word":"der Blick","en":"look; view; glance","ru":"взгляд","vi":"quan điểm","fa":"نمای","examples":[{"de":"Von hier hat man einen schönen Blick auf die Berge.","en":"From here you have a beautiful view of the mountains.","ru":"Отсюда открывается прекрасный вид на горы.","vi":"Từ đây bạn có thể ngắm nhìn những ngọn núi tuyệt đẹp.","fa":"از اینجا منظره زیبایی از کوه ها دارید."},{"de":"Sie warf einen kurzen Blick auf ihre Uhr.","en":"She glanced briefly at her watch.","ru":"Она бросила быстрый взгляд на часы.","vi":"Cô liếc nhìn đồng hồ.","fa":"نگاهی به ساعتش انداخت."}]},{"word":"blind","en":"blind","ru":"слепой","vi":"mù","fa":"کور","examples":[{"de":"Sein Großvater ist seit einem Unfall blind.","en":"His grandfather has been blind since an accident.","ru":"Его дедушка ослеп после аварии.","vi":"Ông nội của anh bị mù từ sau một tai nạn.","fa":"پدربزرگش پس از تصادف نابینا شده است."},{"de":"Blinde Menschen benutzen oft einen Blindenstock.","en":"Blind people often use a white cane.","ru":"Слепые люди часто используют трость.","vi":"Người mù thường sử dụng gậy.","fa":"افراد نابینا اغلب از عصا استفاده می کنند."}]},{"word":"der Blinker","en":"indicator, turn signal (car)","ru":"указатель поворота, поворотник (в машине)","vi":"tín hiệu rẽ","fa":"چراغ راهنما","examples":[{"de":"Vor dem Abbiegen musst du den Blinker setzen.","en":"Before turning you have to use the indicator.","ru":"Перед поворотом нужно включить поворотник.","vi":"Bạn phải sử dụng đèn xi nhan trước khi rẽ.","fa":"قبل از چرخش باید از چراغ راهنما استفاده کنید."},{"de":"Der Fahrer hat vergessen, den Blinker zu betätigen.","en":"The driver forgot to operate the indicator.","ru":"Водитель забыл включить поворотник.","vi":"Người lái xe quên sử dụng đèn xi nhan.","fa":"راننده فراموش کرده از چراغ راهنما استفاده کند."},{"de":"Mein linker Blinker funktioniert nicht mehr.","en":"My left indicator no longer works.","ru":"Мой левый поворотник больше не работает.","vi":"Đèn rẽ trái của tôi không còn hoạt động nữa.","fa":"چراغ راهنمای چپ من دیگر کار نمی کند."}]},{"word":"blitzen","en":"to flash with lightning","ru":"сверкать (о молнии)","vi":"đèn flash","fa":"فلش","examples":[{"de":"Es blitzt und donnert schon seit einer Stunde.","en":"It's been flashing with lightning and thundering for an hour already.","ru":"Уже час сверкает молния и гремит гром.","vi":"Trời đang có sấm sét suốt một giờ đồng hồ.","fa":"یک ساعت است که رعد و برق و رعد و برق است."},{"de":"Als es blitzte, bekam das Kind Angst.","en":"When lightning flashed, the child got scared.","ru":"Когда сверкнула молния, ребёнок испугался.","vi":"Khi có sét, đứa trẻ trở nên sợ hãi.","fa":"وقتی رعد و برق آمد، بچه ترسید."}]},{"word":"blockieren","en":"to block","ru":"блокировать, преграждать","vi":"khối","fa":"مسدود کردن","examples":[{"de":"Ein umgestürzter Baum blockierte die Straße.","en":"A fallen tree blocked the road.","ru":"Упавшее дерево перекрыло дорогу.","vi":"Cây đổ chắn ngang đường.","fa":"درختی که افتاده بود راه را مسدود کرد."},{"de":"Ich habe die unbekannte Nummer auf meinem Handy blockiert.","en":"I blocked the unknown number on my phone.","ru":"Я заблокировал неизвестный номер в телефоне.","vi":"Tôi đã chặn số lạ trên điện thoại di động của mình.","fa":"شماره ناشناس را روی تلفن همراهم مسدود کردم."},{"de":"Bitte blockieren Sie nicht die Ausfahrt.","en":"Please do not block the exit.","ru":"Пожалуйста, не загораживайте выход.","vi":"Xin đừng chặn lối ra.","fa":"لطفا راه خروج را مسدود نکنید."}]},{"word":"blond","en":"blond","ru":"светловолосый","vi":"tóc vàng","fa":"بلوند","examples":[{"de":"Meine Schwester hat blonde Haare.","en":"My sister has blond hair.","ru":"У моей сестры светлые волосы.","vi":"Chị tôi có mái tóc vàng.","fa":"خواهر من موهای بلوند دارد."},{"de":"Das blonde Mädchen dort ist meine Kollegin.","en":"The blond girl over there is my colleague.","ru":"Та светловолосая девушка — моя коллега.","vi":"Cô gái tóc vàng đó là đồng nghiệp của tôi.","fa":"دختر بلوند آنجا همکار من است."}]},{"word":"bloß","en":"only; just","ru":"только, лишь","vi":"chỉ","fa":"فقط","examples":[{"de":"Ich wollte dir bloß helfen.","en":"I just wanted to help you.","ru":"Я лишь хотел тебе помочь.","vi":"Tôi chỉ muốn giúp bạn.","fa":"فقط میخواستم کمکت کنم"},{"de":"Sag mir bloß nicht, dass du den Termin vergessen hast!","en":"Just don't tell me you forgot the appointment!","ru":"Только не говори мне, что ты забыл о встрече!","vi":"Đừng nói với tôi là bạn quên hẹn nhé!","fa":"به من نگو ​​که قرار ملاقات را فراموش کرده ای!"}]},{"word":"blühen","en":"to bloom","ru":"цвести","vi":"nở hoa","fa":"شکوفه دادن","examples":[{"de":"Im Frühling blühen die Blumen im Garten.","en":"In spring the flowers bloom in the garden.","ru":"Весной цветы в саду цветут.","vi":"Vào mùa xuân hoa nở trong vườn.","fa":"در بهار گل ها در باغ شکوفا می شوند."},{"de":"Dieser Baum blüht jedes Jahr im April.","en":"This tree blooms every year in April.","ru":"Это дерево цветёт каждый год в апреле.","vi":"Cây này nở hoa vào tháng Tư hàng năm.","fa":"این درخت هر ماه آوریل شکوفا می شود."}]},{"word":"die Blume","en":"flower","ru":"цветок","vi":"bông hoa","fa":"گل","examples":[{"de":"Er hat seiner Freundin rote Blumen geschenkt.","en":"He gave his girlfriend red flowers.","ru":"Он подарил своей девушке красные цветы.","vi":"Anh tặng bạn gái những bông hoa màu đỏ.","fa":"او به دوست دخترش گل های قرمز داد."},{"de":"Im Garten wachsen viele bunte Blumen.","en":"Many colorful flowers grow in the garden.","ru":"В саду растёт много разноцветных цветов.","vi":"Nhiều loài hoa đủ màu sắc mọc trong vườn.","fa":"گل های رنگارنگ زیادی در باغ می رویند."}]},{"word":"das Blumenmuster","en":"floral pattern","ru":"цветочный узор","vi":"họa tiết hoa","fa":"الگوی گل","examples":[{"de":"Das Kleid mit dem Blumenmuster gefällt mir am besten.","en":"I like the dress with the floral pattern the best.","ru":"Больше всего мне нравится платье с цветочным узором.","vi":"Tôi thích chiếc váy có họa tiết hoa nhất.","fa":"من لباس با طرح گل را بیشتر دوست دارم."},{"de":"Die Tapete hat ein altmodisches Blumenmuster.","en":"The wallpaper has an old-fashioned floral pattern.","ru":"У обоев старомодный цветочный узор.","vi":"Giấy dán tường có họa tiết hoa cổ điển.","fa":"کاغذ دیواری دارای طرح گل های قدیمی است."},{"de":"Sie trägt gern Hemden mit buntem Blumenmuster.","en":"She likes to wear shirts with a colourful floral pattern.","ru":"Она любит носить рубашки с ярким цветочным узором.","vi":"Cô thích mặc áo sơ mi có họa tiết hoa nhiều màu sắc.","fa":"او دوست دارد پیراهن هایی با طرح های رنگارنگ گل بپوشد."}]},{"word":"die Bluse","en":"blouse","ru":"блузка","vi":"chiếc áo cánh","fa":"بلوز","examples":[{"de":"Sie trägt eine weiße Bluse zur Arbeit.","en":"She wears a white blouse to work.","ru":"Она носит белую блузку на работу.","vi":"Cô mặc áo sơ mi trắng đi làm.","fa":"او یک بلوز سفید به سر کار می پوشد."},{"de":"Diese Bluse passt gut zu deinem Rock.","en":"This blouse goes well with your skirt.","ru":"Эта блузка хорошо подходит к твоей юбке.","vi":"Chiếc áo này rất hợp với váy của bạn.","fa":"این بلوز به خوبی با دامن شما می آید."}]},{"word":"bluten","en":"to bleed","ru":"кровоточить","vi":"chảy máu","fa":"خونریزی","examples":[{"de":"Sein Finger blutet, er hat sich geschnitten.","en":"His finger is bleeding, he cut himself.","ru":"У него кровоточит палец, он порезался.","vi":"Ngón tay anh ấy đang chảy máu, anh ấy đã tự cắt mình.","fa":"انگشتش خون است، خودش را بریده است."},{"de":"Die Wunde hat lange geblutet.","en":"The wound bled for a long time.","ru":"Рана долго кровоточила.","vi":"Vết thương chảy máu đã lâu.","fa":"زخم برای مدت طولانی خونریزی کرد."}]},{"word":"der Boden","en":"floor; ground; soil","ru":"пол, земля, почва","vi":"sàn nhà","fa":"کف","examples":[{"de":"Das Kind spielt auf dem Boden im Wohnzimmer.","en":"The child is playing on the floor in the living room.","ru":"Ребёнок играет на полу в гостиной.","vi":"Đứa trẻ đang chơi trên sàn trong phòng khách.","fa":"کودک در اتاق نشیمن روی زمین بازی می کند."},{"de":"In diesem Garten ist der Boden sehr fruchtbar.","en":"In this garden the soil is very fertile.","ru":"В этом саду очень плодородная почва.","vi":"Đất ở khu vườn này rất màu mỡ.","fa":"خاک این باغ بسیار حاصلخیز است."}]},{"word":"der Bogen","en":"arch; sheet (of paper)","ru":"дуга; лист бумаги","vi":"cái cung","fa":"کمان","examples":[{"de":"Die Brücke hat einen schönen Bogen aus Stein.","en":"The bridge has a beautiful stone arch.","ru":"У этого моста красивая каменная арка.","vi":"Cây cầu có vòm đá rất đẹp.","fa":"پل دارای طاق سنگی زیبایی است."},{"de":"Ich brauche noch einen Bogen Papier für den Drucker.","en":"I still need a sheet of paper for the printer.","ru":"Мне ещё нужен лист бумаги для принтера.","vi":"Tôi cần một tờ giấy khác cho máy in.","fa":"من به یک برگه کاغذ دیگر برای چاپگر نیاز دارم."}]},{"word":"die Bohne","en":"bean","ru":"фасоль, боб","vi":"hạt đậu","fa":"لوبیا","examples":[{"de":"Zum Mittagessen gibt es grüne Bohnen mit Kartoffeln.","en":"For lunch there are green beans with potatoes.","ru":"На обед будет зелёная фасоль с картошкой.","vi":"Bữa trưa chúng tôi ăn đậu xanh với khoai tây.","fa":"برای ناهار لوبیا سبز با سیب زمینی داریم."},{"de":"Meine Oma pflanzt jedes Jahr Bohnen im Garten.","en":"My grandma plants beans in the garden every year.","ru":"Моя бабушка каждый год сажает фасоль в саду.","vi":"Bà tôi trồng đậu trong vườn hàng năm.","fa":"مادربزرگ من هر سال در باغ لوبیا می کارد."}]},{"word":"die Bohrmaschine","en":"drill (power tool)","ru":"дрель","vi":"mũi khoan","fa":"مته","examples":[{"de":"Mit der Bohrmaschine mache ich ein Loch in die Wand.","en":"With the drill I make a hole in the wall.","ru":"Дрелью я делаю отверстие в стене.","vi":"Tôi dùng máy khoan để tạo một lỗ trên tường.","fa":"من از مته برای ایجاد سوراخ در دیوار استفاده می کنم."},{"de":"Kannst du mir deine Bohrmaschine ausleihen?","en":"Can you lend me your drill?","ru":"Ты можешь одолжить мне свою дрель?","vi":"Bạn có thể cho tôi mượn máy khoan của bạn được không?","fa":"آیا می توانید دریل خود را به من قرض دهید؟"},{"de":"Die neue Bohrmaschine ist viel leiser als die alte.","en":"The new drill is much quieter than the old one.","ru":"Новая дрель гораздо тише старой.","vi":"Máy khoan mới êm hơn nhiều so với máy cũ.","fa":"مته جدید بسیار کم صداتر از مته قدیمی است."}]},{"word":"das Boot","en":"boat","ru":"лодка","vi":"chiếc thuyền","fa":"قایق","examples":[{"de":"Wir sind mit dem Boot über den See gefahren.","en":"We crossed the lake by boat.","ru":"Мы переплыли озеро на лодке.","vi":"Chúng tôi đi thuyền qua hồ.","fa":"با قایق از کنار دریاچه عبور کردیم."},{"de":"Am Wochenende mieten wir ein kleines Boot.","en":"On the weekend we're renting a small boat.","ru":"В выходные мы арендуем маленькую лодку.","vi":"Cuối tuần chúng tôi thuê một chiếc thuyền nhỏ.","fa":"در آخر هفته یک قایق کوچک کرایه می کنیم."}]},{"word":"die Bordkarte","en":"boarding pass","ru":"посадочный талон","vi":"thẻ lên máy bay","fa":"کارت پرواز","examples":[{"de":"Halten Sie bitte Ihre Bordkarte am Gate bereit.","en":"Please have your boarding pass ready at the gate.","ru":"Пожалуйста, держите посадочный талон наготове у выхода на посадку.","vi":"Vui lòng chuẩn bị sẵn thẻ lên máy bay ở cổng.","fa":"لطفا کارت پرواز خود را در دروازه آماده کنید."},{"de":"Ich habe meine Bordkarte aufs Handy geladen.","en":"I downloaded my boarding pass onto my phone.","ru":"Я загрузил свой посадочный талон на телефон.","vi":"Tôi đã tải thẻ lên máy bay xuống điện thoại của mình.","fa":"کارت پروازم را روی گوشیم دانلود کردم."},{"de":"Ohne Bordkarte darfst du nicht ins Flugzeug.","en":"Without a boarding pass you can't get on the plane.","ru":"Без посадочного талона ты не попадёшь в самолёт.","vi":"Bạn không được phép lên máy bay nếu không có thẻ lên máy bay.","fa":"بدون کارت پرواز اجازه ورود به هواپیما را ندارید."}]},{"word":"böse","en":"angry; evil","ru":"злой, сердитый","vi":"tà ác","fa":"بد","examples":[{"de":"Meine Mutter war böse, weil ich zu spät kam.","en":"My mother was angry because I came too late.","ru":"Моя мама была сердита, потому что я пришёл слишком поздно.","vi":"Mẹ tôi tức giận vì tôi đến muộn.","fa":"مادرم به خاطر دیر آمدن من عصبانی بود."},{"de":"In dem Märchen gibt es eine böse Hexe.","en":"In the fairy tale there is an evil witch.","ru":"В этой сказке есть злая ведьма.","vi":"Trong truyện cổ tích có một mụ phù thủy độc ác.","fa":"در افسانه یک جادوگر شیطانی وجود دارد."}]},{"word":"die Botschaft","en":"embassy; message","ru":"посольство; послание","vi":"tin nhắn","fa":"پیام","examples":[{"de":"Für das Visum musste ich zur Botschaft gehen.","en":"For the visa I had to go to the embassy.","ru":"Для визы мне пришлось пойти в посольство.","vi":"Tôi phải đến đại sứ quán để xin visa.","fa":"برای ویزا باید برم سفارت."},{"de":"Er hinterließ ihr eine wichtige Botschaft.","en":"He left her an important message.","ru":"Он оставил ей важное послание.","vi":"Anh để lại cho cô một tin nhắn quan trọng.","fa":"او یک پیام مهم برای او گذاشت."}]},{"word":"die Branche","en":"industry, sector","ru":"отрасль, сфера","vi":"ngành công nghiệp","fa":"صنعت","examples":[{"de":"In unserer Branche ist die Konkurrenz sehr stark.","en":"In our industry the competition is very strong.","ru":"В нашей отрасли очень сильная конкуренция.","vi":"Sự cạnh tranh trong ngành của chúng tôi rất mạnh mẽ.","fa":"رقابت در صنعت ما بسیار قوی است."},{"de":"Sie hat zwanzig Jahre Erfahrung in dieser Branche.","en":"She has twenty years of experience in this sector.","ru":"У неё двадцать лет опыта в этой сфере.","vi":"Cô có hai mươi năm kinh nghiệm trong ngành này.","fa":"او بیست سال تجربه در این صنعت دارد."},{"de":"Die ganze Branche leidet unter dem Fachkräftemangel.","en":"The whole industry is suffering from the shortage of skilled workers.","ru":"Вся отрасль страдает от нехватки квалифицированных кадров.","vi":"Toàn bộ ngành công nghiệp đang thiếu hụt lao động có tay nghề cao.","fa":"کل صنعت از کمبود نیروی کار ماهر رنج می برد."}]},{"word":"braten","en":"to fry; to roast","ru":"жарить","vi":"chiên","fa":"سرخ کردن","examples":[{"de":"Sie brät das Fleisch in der Pfanne.","en":"She fries the meat in the pan.","ru":"Она жарит мясо на сковороде.","vi":"Cô chiên thịt trong chảo.","fa":"او گوشت را در تابه سرخ می کند."},{"de":"Wir braten am Sonntag ein Hähnchen.","en":"We're roasting a chicken on Sunday.","ru":"В воскресенье мы жарим курицу.","vi":"Chúng tôi sẽ nướng gà vào ngày chủ nhật.","fa":"یکشنبه داریم جوجه کباب میکنیم."}]},{"word":"die Bratpfanne","en":"frying pan","ru":"сковорода","vi":"chảo rán","fa":"ماهیتابه","examples":[{"de":"Erhitze etwas Öl in der Bratpfanne.","en":"Heat some oil in the frying pan.","ru":"Разогрей немного масла на сковороде.","vi":"Đun nóng một ít dầu trong chảo.","fa":"در ماهیتابه مقداری روغن داغ کنید."},{"de":"Die Eier brutzeln schon in der Bratpfanne.","en":"The eggs are already sizzling in the frying pan.","ru":"Яйца уже шипят на сковороде.","vi":"Trứng đã nóng hổi trong chảo rồi.","fa":"تخم مرغ ها از قبل در ماهیتابه می جوشند."},{"de":"Eine gute Bratpfanne hält viele Jahre.","en":"A good frying pan lasts for many years.","ru":"Хорошая сковорода служит много лет.","vi":"Một chiếc chảo rán tốt sẽ tồn tại được trong nhiều năm.","fa":"یک ماهیتابه خوب تا سال ها دوام می آورد."}]},{"word":"brauchen","en":"to need","ru":"нуждаться","vi":"cần","fa":"نیاز دارند","examples":[{"de":"Ich brauche mehr Zeit für dieses Projekt.","en":"I need more time for this project.","ru":"Мне нужно больше времени для этого проекта.","vi":"Tôi cần thêm thời gian cho dự án này.","fa":"برای این پروژه به زمان بیشتری نیاز دارم."},{"de":"Brauchst du Hilfe beim Umzug?","en":"Do you need help with the move?","ru":"Тебе нужна помощь с переездом?","vi":"Bạn có cần giúp đỡ di chuyển?","fa":"آیا برای حرکت به کمک نیاز دارید؟"}]},{"word":"die Brause","en":"fizzy drink, pop","ru":"шипучка, газировка","vi":"vòi hoa sen","fa":"دوش","examples":[{"de":"Die Kinder bekamen zum Geburtstag eine süße Brause.","en":"The children got a sweet fizzy drink for the birthday.","ru":"Дети получили на день рождения сладкую шипучку.","vi":"Các em đã nhận được soda ngọt nhân ngày sinh nhật của mình.","fa":"بچه ها برای تولدشان یک نوشابه شیرین دریافت کردند."},{"de":"Im Sommer trinke ich gern eine kühle Brause.","en":"In summer I like to drink a cool fizzy drink.","ru":"Летом я люблю пить прохладную газировку.","vi":"Vào mùa hè tôi thích uống soda mát.","fa":"در تابستان من دوست دارم یک نوشابه خنک بنوشم."},{"de":"Diese Brause schmeckt nach Waldmeister.","en":"This fizzy drink tastes of woodruff.","ru":"Эта шипучка на вкус как ясменник.","vi":"Loại soda này có vị như mùi gỗ.","fa":"این نوشابه طعمی شبیه به چوب دارد."}]},{"word":"brechen","en":"to break","ru":"ломать","vi":"phá vỡ","fa":"شکستن","examples":[{"de":"Er hat sich beim Skifahren das Bein gebrochen.","en":"He broke his leg while skiing.","ru":"Он сломал ногу, катаясь на лыжах.","vi":"Anh ấy bị gãy chân khi trượt tuyết.","fa":"هنگام اسکی پایش شکست."},{"de":"Pass auf, dass das Glas nicht bricht!","en":"Be careful the glass doesn't break!","ru":"Осторожно, чтобы стекло не разбилось!","vi":"Hãy cẩn thận để không làm vỡ kính!","fa":"مراقب باشید که شیشه نشکند!"}]},{"word":"die Brechung","en":"refraction","ru":"преломление (света)","vi":"sự khúc xạ","fa":"شکست","examples":[{"de":"Durch die Brechung wirkt der Strohhalm im Glas geknickt.","en":"Because of refraction, the straw in the glass appears bent.","ru":"Из-за преломления соломинка в стакане кажется надломленной.","vi":"Sự khúc xạ làm cho ống hút trông như bị uốn cong trong thủy tinh.","fa":"شکست باعث می شود که نی در شیشه خمیده به نظر برسد."},{"de":"Die Brechung tritt auf, wenn Licht in ein anderes Material übergeht.","en":"Refraction occurs when light passes into a different medium.","ru":"Преломление возникает, когда свет переходит в другую среду.","vi":"Khúc xạ xảy ra khi ánh sáng truyền vào vật liệu khác.","fa":"شکست زمانی اتفاق می‌افتد که نور به ماده دیگری وارد شود."},{"de":"Eine Linse nutzt die Brechung, um Licht zu bündeln.","en":"A lens uses refraction to focus light.","ru":"Линза использует преломление, чтобы собирать свет.","vi":"Một thấu kính sử dụng khúc xạ để tập trung ánh sáng.","fa":"یک لنز از شکست برای تمرکز نور استفاده می کند."}]},{"word":"breit","en":"wide","ru":"широкий","vi":"rộng","fa":"گسترده","examples":[{"de":"Die Straße vor unserem Haus ist sehr breit.","en":"The street in front of our house is very wide.","ru":"Улица перед нашим домом очень широкая.","vi":"Con đường trước nhà chúng tôi rất rộng.","fa":"خیابون جلوی خونه ما خیلی عریضه."},{"de":"Er hat breite Schultern.","en":"He has broad shoulders.","ru":"У него широкие плечи.","vi":"Anh ấy có bờ vai rộng.","fa":"او شانه های پهنی دارد."}]},{"word":"die Bremse","en":"brake","ru":"тормоз","vi":"phanh","fa":"ترمز","examples":[{"de":"Die Bremse meines Fahrrads funktioniert nicht richtig.","en":"The brake of my bicycle doesn't work properly.","ru":"Тормоз моего велосипеда работает неправильно.","vi":"Phanh trên xe đạp của tôi không hoạt động bình thường.","fa":"ترمز دوچرخه من درست کار نمی کند."},{"de":"Er trat plötzlich auf die Bremse, weil ein Kind über die Straße lief.","en":"He suddenly stepped on the brake because a child ran across the street.","ru":"Он резко нажал на тормоз, потому что ребёнок выбежал на дорогу.","vi":"Anh ta đột ngột phanh gấp vì có một đứa trẻ đang chạy qua đường.","fa":"او ناگهان به ترمز زد، زیرا کودکی از خیابان می دوید."},{"de":"Die Bremsen am Auto müssen dringend repariert werden.","en":"The brakes on the car urgently need to be repaired.","ru":"Тормоза машины срочно нужно отремонтировать.","vi":"Hệ thống phanh trên ô tô cần được sửa chữa khẩn cấp.","fa":"ترمزهای خودرو نیاز به تعمیر فوری دارند."}]},{"word":"bremsen","en":"to brake","ru":"тормозить","vi":"phanh","fa":"ترمز","examples":[{"de":"Der Fahrer musste plötzlich stark bremsen.","en":"The driver had to brake hard suddenly.","ru":"Водителю пришлось резко затормозить.","vi":"Tài xế bất ngờ phải phanh gấp.","fa":"راننده ناگهان مجبور شد به شدت ترمز کند."},{"de":"Auf nasser Straße sollte man vorsichtig bremsen.","en":"On a wet road you should brake carefully.","ru":"На мокрой дороге нужно тормозить осторожно.","vi":"Bạn nên phanh cẩn thận trên đường ướt.","fa":"در جاده های خیس باید با احتیاط ترمز کنید."}]},{"word":"brennen","en":"to burn","ru":"гореть","vi":"đốt cháy","fa":"سوختن","examples":[{"de":"Im Kamin brennt ein warmes Feuer.","en":"A warm fire is burning in the fireplace.","ru":"В камине горит тёплый огонь.","vi":"Ngọn lửa ấm áp đang cháy trong lò sưởi.","fa":"آتش گرمی در شومینه می سوزد."},{"de":"Meine Augen brennen vom Rauch.","en":"My eyes are burning from the smoke.","ru":"Мои глаза жжёт от дыма.","vi":"Mắt tôi bỏng rát vì khói.","fa":"چشمانم از دود می سوزد."}]},{"word":"der Brennstoff","en":"fuel","ru":"топливо, горючее","vi":"nhiên liệu","fa":"سوخت","examples":[{"de":"Kohle und Öl sind fossile Brennstoffe.","en":"Coal and oil are fossil fuels.","ru":"Уголь и нефть — ископаемые виды топлива.","vi":"Than và dầu là nhiên liệu hóa thạch.","fa":"زغال سنگ و نفت سوخت های فسیلی هستند."},{"de":"Beim Verbrennen von Brennstoffen entsteht viel CO2.","en":"Burning fuels produces a lot of CO2.","ru":"При сжигании топлива образуется много CO2.","vi":"Nhiên liệu đốt sinh ra rất nhiều CO2.","fa":"سوختن سوخت مقدار زیادی CO2 تولید می کند."},{"de":"Wir müssen fossile Brennstoffe durch saubere Energie ersetzen.","en":"We have to replace fossil fuels with clean energy.","ru":"Мы должны заменить ископаемое топливо чистой энергией.","vi":"Chúng ta phải thay thế nhiên liệu hóa thạch bằng năng lượng sạch.","fa":"ما باید انرژی های پاک را جایگزین سوخت های فسیلی کنیم."}]},{"word":"der Brief","en":"letter","ru":"письмо","vi":"lá thư","fa":"نامه","examples":[{"de":"Ich habe meiner Freundin einen langen Brief geschrieben.","en":"I wrote my friend a long letter.","ru":"Я написал своей подруге длинное письмо.","vi":"Tôi đã viết một lá thư dài cho bạn gái của tôi.","fa":"من یک نامه طولانی به دوست دخترم نوشتم."},{"de":"Hast du den Brief schon zur Post gebracht?","en":"Have you already taken the letter to the post office?","ru":"Ты уже отнёс письмо на почту?","vi":"Bạn đã gửi thư chưa?","fa":"آیا قبلا نامه را پست کرده اید؟"}]},{"word":"der Briefkasten","en":"letterbox, postbox","ru":"почтовый ящик","vi":"hộp thư","fa":"صندوق پستی","examples":[{"de":"Jeden Morgen schaue ich in den Briefkasten.","en":"Every morning I look in the letterbox.","ru":"Каждое утро я заглядываю в почтовый ящик.","vi":"Mỗi buổi sáng tôi đều nhìn vào hộp thư.","fa":"هر روز صبح به صندوق پستی نگاه می کنم."},{"de":"Bitte wirf den Brief in den Briefkasten an der Ecke.","en":"Please drop the letter in the postbox on the corner.","ru":"Пожалуйста, брось письмо в почтовый ящик на углу.","vi":"Vui lòng đặt bức thư vào hộp thư ở góc.","fa":"لطفا نامه را در صندوق پستی گوشه ای قرار دهید."},{"de":"Unser Briefkasten ist heute leer geblieben.","en":"Our letterbox stayed empty today.","ru":"Наш почтовый ящик сегодня остался пустым.","vi":"Hộp thư của chúng tôi vẫn trống ngày hôm nay.","fa":"صندوق پست ما امروز خالی ماند."}]},{"word":"die Brieftasche","en":"wallet","ru":"кошелёк, бумажник","vi":"cái ví","fa":"کیف پول","examples":[{"de":"Ich habe meine Brieftasche im Bus vergessen.","en":"I forgot my wallet on the bus.","ru":"Я забыл свой бумажник в автобусе.","vi":"Tôi quên ví trên xe buýt.","fa":"کیف پولم را در اتوبوس فراموش کردم."},{"de":"In seiner Brieftasche sind Geld und Ausweis.","en":"His wallet has money and an ID card in it.","ru":"В его бумажнике деньги и удостоверение личности.","vi":"Có tiền và giấy tờ tùy thân trong ví của anh ấy.","fa":"در کیف پولش پول و شناسنامه هست."}]},{"word":"der Briefträger","en":"postman (male)","ru":"почтальон (мужчина)","vi":"người đưa thư","fa":"پستچی","examples":[{"de":"Der Briefträger bringt die Post meistens am Vormittag.","en":"The postman usually delivers the post in the morning.","ru":"Почтальон обычно приносит почту утром.","vi":"Người đưa thư thường đưa thư vào buổi sáng.","fa":"پستچی معمولاً نامه را صبح ها تحویل می دهد."},{"de":"Unser Briefträger kennt jeden im Viertel.","en":"Our postman knows everyone in the neighbourhood.","ru":"Наш почтальон знает всех в квартале.","vi":"Người đưa thư của chúng tôi biết tất cả mọi người trong khu phố.","fa":"پستچی ما همه را در محله می شناسد."},{"de":"Der Briefträger hat ein Päckchen für dich abgegeben.","en":"The postman left a small parcel for you.","ru":"Почтальон оставил для тебя небольшую посылку.","vi":"Người đưa thư đã gửi một gói hàng cho bạn.","fa":"پستچی بسته ای را برای شما انداخت."}]},{"word":"die Briefträgerin","en":"postwoman","ru":"почтальон (женщина)","vi":"người đưa thư","fa":"پست زن","examples":[{"de":"Die Briefträgerin klingelte, weil ein Paket nicht in den Briefkasten passte.","en":"The postwoman rang the bell because a parcel didn't fit in the letterbox.","ru":"Почтальонка позвонила в дверь, потому что посылка не помещалась в ящик.","vi":"Người đưa thư bấm chuông vì một gói hàng không vừa trong hộp thư.","fa":"پستچی زنگ را زد چون بسته ای در صندوق پست جا نمی شد."},{"de":"Unsere Briefträgerin arbeitet seit zehn Jahren in diesem Viertel.","en":"Our postwoman has worked in this neighbourhood for ten years.","ru":"Наша почтальонка работает в этом квартале уже десять лет.","vi":"Người đưa thư của chúng tôi đã làm việc trong lĩnh vực này được mười năm.","fa":"پست خانم ما ده سال است که در این منطقه کار می کند."},{"de":"Die Briefträgerin fährt jeden Tag mit dem Fahrrad.","en":"The postwoman rides her bicycle every day.","ru":"Почтальонка каждый день ездит на велосипеде.","vi":"Người đưa thư đạp xe hàng ngày.","fa":"پستچی هر روز دوچرخه سواری می کند."}]},{"word":"der Briefumschlag","en":"envelope","ru":"конверт","vi":"phong bì","fa":"پاکت نامه","examples":[{"de":"Ich klebe die Briefmarke auf den Briefumschlag.","en":"I stick the stamp on the envelope.","ru":"Я приклеиваю марку на конверт.","vi":"Tôi dán tem lên phong bì.","fa":"مهر را روی پاکت می چسبانم."},{"de":"Sie legte das Foto in den Briefumschlag.","en":"She put the photo in the envelope.","ru":"Она положила фото в конверт.","vi":"Cô nhét bức ảnh vào phong bì.","fa":"او عکس را در پاکت گذاشت."}]},{"word":"die Brille","en":"glasses","ru":"очки","vi":"cái kính","fa":"عینک","examples":[{"de":"Ohne Brille kann ich nicht gut lesen.","en":"Without glasses I can't read well.","ru":"Без очков я плохо вижу при чтении.","vi":"Tôi không thể đọc tốt nếu không có kính.","fa":"بدون عینک نمی توانم خوب بخوانم."},{"de":"Er trägt seit Kurzem eine neue Brille.","en":"He's recently been wearing new glasses.","ru":"Он недавно начал носить новые очки.","vi":"Gần đây anh ấy đã bắt đầu đeo kính mới.","fa":"او اخیراً شروع به استفاده از عینک جدید کرده است."}]},{"word":"bringen","en":"to bring","ru":"приносить","vi":"mang theo","fa":"آوردن","examples":[{"de":"Kannst du mir bitte ein Glas Wasser bringen?","en":"Can you bring me a glass of water, please?","ru":"Можешь принести мне стакан воды?","vi":"Bạn có thể vui lòng mang cho tôi một cốc nước được không?","fa":"میشه لطفا یه لیوان آب برام بیارید؟"},{"de":"Der Kellner bringt uns gleich die Speisekarte.","en":"The waiter will bring us the menu shortly.","ru":"Официант сейчас принесёт нам меню.","vi":"Người phục vụ mang thực đơn đến cho chúng tôi ngay lập tức.","fa":"گارسون فوراً منو را برای ما می آورد."}]},{"word":"die Broschüre","en":"brochure","ru":"брошюра","vi":"tờ rơi","fa":"بروشور","examples":[{"de":"Am Bahnhof gibt es eine Broschüre über die Stadt.","en":"At the train station there's a brochure about the city.","ru":"На вокзале есть брошюра о городе.","vi":"Có một tập tài liệu về thành phố ở ga xe lửa.","fa":"یک بروشور در مورد شهر در ایستگاه قطار وجود دارد."},{"de":"Im Reisebüro bekam ich viele Broschüren.","en":"At the travel agency I got many brochures.","ru":"В турагентстве я получил много брошюр.","vi":"Tôi nhận được rất nhiều tài liệu quảng cáo tại công ty du lịch.","fa":"من بروشورهای زیادی در آژانس مسافرتی گرفتم."}]},{"word":"das Brot","en":"bread","ru":"хлеб","vi":"bánh mì","fa":"نان","examples":[{"de":"Jeden Morgen kaufe ich frisches Brot beim Bäcker.","en":"Every morning I buy fresh bread at the bakery.","ru":"Каждое утро я покупаю свежий хлеб в пекарне.","vi":"Mỗi sáng tôi mua bánh mì tươi từ tiệm bánh.","fa":"هر روز صبح از نانوایی نان تازه می خرم."},{"de":"Zum Frühstück esse ich Brot mit Marmelade.","en":"For breakfast I eat bread with jam.","ru":"На завтрак я ем хлеб с джемом.","vi":"Bữa sáng tôi ăn bánh mì với mứt.","fa":"برای صبحانه نان با مربا می خورم."}]},{"word":"das Brötchen","en":"bread roll","ru":"булочка","vi":"cái bánh bao","fa":"نان","examples":[{"de":"Wir haben heute Morgen frische Brötchen gekauft.","en":"We bought fresh bread rolls this morning.","ru":"Сегодня утром мы купили свежие булочки.","vi":"Chúng tôi đã mua bánh mì tươi sáng nay.","fa":"امروز صبح نان رول تازه خریدیم."},{"de":"Ein Brötchen mit Käse ist mein Lieblingsfrühstück.","en":"A roll with cheese is my favorite breakfast.","ru":"Булочка с сыром — мой любимый завтрак.","vi":"Bánh mì cuộn phô mai là bữa sáng yêu thích của tôi.","fa":"رول با پنیر صبحانه مورد علاقه من است."}]},{"word":"das Brötli","en":"bread roll (Swiss German)","ru":"булочка (швейцарский вариант)","vi":"bánh mì cuộn","fa":"رول نان","examples":[{"de":"In der Schweiz kaufe ich morgens frische Brötli beim Bäcker.","en":"In Switzerland I buy fresh bread rolls at the baker's in the morning.","ru":"В Швейцарии я по утрам покупаю у пекаря свежие булочки.","vi":"Ở Thụy Sĩ, tôi mua bánh mì tươi ở tiệm bánh vào buổi sáng.","fa":"در سوئیس من صبح ها نان رول های تازه را از نانوایی می خرم."},{"de":"Möchtest du ein Brötli mit Käse zum Frühstück?","en":"Would you like a bread roll with cheese for breakfast?","ru":"Хочешь булочку с сыром на завтрак?","vi":"Bạn có muốn ăn bánh mì cuộn phô mai cho bữa sáng không?","fa":"آیا برای صبحانه نان رول با پنیر میل دارید؟"},{"de":"Die Brötli sind heute noch ganz warm.","en":"The bread rolls are still quite warm today.","ru":"Булочки сегодня ещё совсем тёплые.","vi":"Bánh mì cuộn hôm nay vẫn còn rất ấm áp.","fa":"نان رول ها امروز هنوز خیلی گرم هستند."}]},{"word":"der Browser","en":"browser","ru":"браузер","vi":"trình duyệt","fa":"مرورگر","examples":[{"de":"Öffne den Link in einem neuen Browser.","en":"Open the link in a new browser.","ru":"Открой ссылку в новом браузере.","vi":"Mở liên kết trong một trình duyệt mới.","fa":"لینک را در یک مرورگر جدید باز کنید."},{"de":"Mein Browser zeigt die Seite nicht richtig an.","en":"My browser isn't displaying the page correctly.","ru":"Мой браузер неправильно отображает страницу.","vi":"Trình duyệt của tôi không hiển thị trang chính xác.","fa":"مرورگر من صفحه را به درستی نمایش نمی دهد."},{"de":"Lösche regelmäßig den Verlauf in deinem Browser.","en":"Regularly delete the history in your browser.","ru":"Регулярно удаляй историю в своём браузере.","vi":"Thường xuyên xóa lịch sử trong trình duyệt của bạn.","fa":"به طور منظم تاریخچه را در مرورگر خود پاک کنید."}]},{"word":"die Brücke","en":"bridge","ru":"мост","vi":"cây cầu","fa":"پل","examples":[{"de":"Wir überqueren die Brücke, um zum Bahnhof zu kommen.","en":"We cross the bridge to get to the train station.","ru":"Мы переходим мост, чтобы попасть на вокзал.","vi":"Chúng tôi băng qua cầu để đến ga xe lửa.","fa":"از روی پل عبور می کنیم تا به ایستگاه قطار برسیم."},{"de":"Diese Brücke über den Fluss ist sehr alt.","en":"This bridge over the river is very old.","ru":"Этот мост через реку очень старый.","vi":"Cây cầu bắc qua sông này rất cũ.","fa":"این پل روی رودخانه بسیار قدیمی است."}]},{"word":"der Bruder","en":"brother","ru":"брат","vi":"anh trai","fa":"برادر","examples":[{"de":"Mein Bruder ist zwei Jahre älter als ich.","en":"My brother is two years older than me.","ru":"Мой брат на два года старше меня.","vi":"Anh trai tôi hơn tôi hai tuổi.","fa":"برادرم دو سال از من بزرگتر است."},{"de":"Ich habe einen kleinen Bruder.","en":"I have a little brother.","ru":"У меня есть младший брат.","vi":"Tôi có một em trai.","fa":"من یک برادر کوچک دارم."}]},{"word":"die Brust","en":"chest; breast","ru":"грудь","vi":"ngực","fa":"قفسه سینه","examples":[{"de":"Nach dem Sturz tat ihm die Brust weh.","en":"After the fall his chest hurt.","ru":"После падения у него болела грудь.","vi":"Ngực anh đau sau cú ngã.","fa":"سینه اش بعد از زمین خوردن درد می کرد."},{"de":"Der Arzt hörte seine Brust ab.","en":"The doctor listened to his chest.","ru":"Врач прослушал его грудную клетку.","vi":"Bác sĩ lắng nghe lồng ngực của mình.","fa":"دکتر به قفسه سینه اش گوش داد."}]},{"word":"der Bub","en":"boy","ru":"мальчик","vi":"cậu bé","fa":"پسر","examples":[{"de":"Der kleine Bub spielt mit seinem Ball im Garten.","en":"The little boy is playing with his ball in the garden.","ru":"Маленький мальчик играет с мячом в саду.","vi":"Cậu bé chơi với quả bóng của mình trong vườn.","fa":"پسر کوچک در باغ با توپش بازی می کند."},{"de":"In der Schweiz sagt man oft \"Bub\" statt \"Junge\".","en":"In Switzerland people often say \"Bub\" instead of \"Junge\".","ru":"В Швейцарии часто говорят «Bub» вместо «Junge».","vi":"Ở Thụy Sĩ người ta thường nói “Bub” thay vì “Junge”.","fa":"در سوئیس مردم اغلب به جای \"Junge\" \"Bub\" می گویند."}]},{"word":"das Buch","en":"book","ru":"книга","vi":"cuốn sách","fa":"کتاب","examples":[{"de":"Ich lese gerade ein spannendes Buch.","en":"I'm currently reading an exciting book.","ru":"Я сейчас читаю увлекательную книгу.","vi":"Hiện tại tôi đang đọc một cuốn sách thú vị.","fa":"در حال حاضر مشغول خواندن یک کتاب هیجان انگیز هستم."},{"de":"Sie hat mir ein Buch zum Geburtstag geschenkt.","en":"She gave me a book for my birthday.","ru":"Она подарила мне книгу на день рождения.","vi":"Cô ấy tặng tôi một cuốn sách vào ngày sinh nhật của tôi.","fa":"او برای تولدم به من کتاب داد."}]},{"word":"buchen","en":"to book","ru":"бронировать","vi":"cuốn sách","fa":"کتاب","examples":[{"de":"Wir haben unseren Flug schon vor drei Monaten gebucht.","en":"We booked our flight three months ago already.","ru":"Мы забронировали наш рейс уже три месяца назад.","vi":"Chúng tôi đã đặt chuyến bay ba tháng trước.","fa":"ما پروازمان را سه ماه پیش رزرو کردیم."},{"de":"Ich möchte ein Zimmer für zwei Nächte buchen.","en":"I would like to book a room for two nights.","ru":"Я хотел бы забронировать номер на две ночи.","vi":"Tôi muốn đặt một phòng trong hai đêm.","fa":"من می خواهم یک اتاق برای دو شب رزرو کنم."}]},{"word":"die Buchhandlung","en":"bookshop","ru":"книжный магазин","vi":"hiệu sách","fa":"کتابفروشی","examples":[{"de":"In der Buchhandlung habe ich ein neues Wörterbuch gekauft.","en":"At the bookshop I bought a new dictionary.","ru":"В книжном магазине я купил новый словарь.","vi":"Tôi đã mua một cuốn từ điển mới ở hiệu sách.","fa":"از کتابفروشی یک دیکشنری جدید خریدم."},{"de":"Die Buchhandlung in der Altstadt ist sehr gemütlich.","en":"The bookshop in the old town is very cozy.","ru":"Книжный магазин в старом городе очень уютный.","vi":"Hiệu sách trong phố cổ rất ấm cúng.","fa":"کتابفروشی در شهر قدیمی بسیار دنج است."}]},{"word":"die Büchse","en":"can; tin; box","ru":"банка, коробка","vi":"cái lon","fa":"قوطی","examples":[{"de":"Sie öffnete eine Büchse Bohnen für das Abendessen.","en":"She opened a can of beans for dinner.","ru":"Она открыла банку фасоли на ужин.","vi":"Cô mở hộp đậu cho bữa tối.","fa":"یک قوطی لوبیا برای شام باز کرد."},{"de":"Der Hund frisst Futter aus der Büchse.","en":"The dog eats food from the can.","ru":"Собака ест корм из банки.","vi":"Con chó ăn thức ăn từ hộp.","fa":"سگ از قوطی غذا می خورد."}]},{"word":"buchstabieren","en":"to spell","ru":"произносить по буквам","vi":"đánh vần","fa":"طلسم","examples":[{"de":"Können Sie bitte Ihren Namen buchstabieren?","en":"Could you please spell your name?","ru":"Не могли бы вы произнести своё имя по буквам?","vi":"Bạn có thể vui lòng đánh vần tên của bạn?","fa":"میشه لطفا اسمتو بنویسی"},{"de":"Das Kind lernt gerade, einfache Wörter zu buchstabieren.","en":"The child is currently learning to spell simple words.","ru":"Ребёнок сейчас учится произносить простые слова по буквам.","vi":"Trẻ hiện đang học cách đánh vần những từ đơn giản.","fa":"کودک در حال حاضر در حال یادگیری املای کلمات ساده است."}]},{"word":"die Buchung","en":"booking, reservation","ru":"бронирование, заказ","vi":"việc đặt chỗ","fa":"رزرو","examples":[{"de":"Die Buchung des Hotels hat problemlos geklappt.","en":"The hotel booking went through without any trouble.","ru":"Бронирование отеля прошло без проблем.","vi":"Đặt phòng khách sạn diễn ra suôn sẻ.","fa":"رزرو هتل بدون مشکل انجام شد."},{"de":"Bitte bestätigen Sie Ihre Buchung per E-Mail.","en":"Please confirm your booking by email.","ru":"Пожалуйста, подтвердите ваше бронирование по электронной почте.","vi":"Vui lòng xác nhận đặt chỗ của bạn qua email.","fa":"لطفا رزرو خود را از طریق ایمیل تایید کنید."},{"de":"Eine kostenlose Stornierung der Buchung ist bis morgen möglich.","en":"A free cancellation of the booking is possible until tomorrow.","ru":"Бесплатная отмена бронирования возможна до завтра.","vi":"Việc hủy đặt phòng miễn phí có thể được thực hiện cho đến ngày mai.","fa":"کنسلی رایگان رزرو تا فردا امکان پذیر است."}]},{"word":"das Budget","en":"budget","ru":"бюджет","vi":"ngân sách","fa":"بودجه","examples":[{"de":"Wir müssen unser Budget für den Urlaub planen.","en":"We have to plan our budget for the holiday.","ru":"Нам нужно спланировать бюджет на отпуск.","vi":"Chúng ta cần lập kế hoạch ngân sách cho kỳ nghỉ.","fa":"ما باید بودجه خود را برای تعطیلات برنامه ریزی کنیم."},{"de":"Das Budget ist diesen Monat schon fast aufgebraucht.","en":"The budget is almost used up this month already.","ru":"Бюджет в этом месяце уже почти израсходован.","vi":"Ngân sách tháng này gần như cạn kiệt.","fa":"بودجه این ماه تقریبا تمام شده است."},{"de":"Für neue Möbel haben wir kein Budget mehr.","en":"We have no budget left for new furniture.","ru":"На новую мебель у нас не осталось бюджета.","vi":"Chúng tôi không còn đủ ngân sách cho đồ nội thất mới.","fa":"ما دیگر بودجه ای برای مبلمان جدید نداریم."}]},{"word":"das Büfett","en":"buffet (German spelling)","ru":"фуршет, шведский стол (немецкое написание)","vi":"bữa tiệc buffet","fa":"بوفه","examples":[{"de":"Das Büfett im Restaurant war wirklich reichhaltig.","en":"The buffet in the restaurant was really plentiful.","ru":"Шведский стол в ресторане был действительно обильным.","vi":"Buffet ở nhà hàng rất phong phú.","fa":"بوفه رستوران واقعا غنی بود."},{"de":"Für die Hochzeit haben wir ein kaltes Büfett bestellt.","en":"For the wedding we ordered a cold buffet.","ru":"На свадьбу мы заказали холодный фуршет.","vi":"Chúng tôi đã gọi một bữa tiệc buffet nguội cho đám cưới.","fa":"برای عروسی بوفه سرد سفارش دادیم."},{"de":"Am Büfett standen viele verschiedene Salate.","en":"At the buffet there were many different salads.","ru":"На шведском столе было много разных салатов.","vi":"Có nhiều món salad khác nhau trong bữa tiệc buffet.","fa":"در بوفه سالادهای مختلفی وجود داشت."}]},{"word":"das Buffet","en":"buffet","ru":"фуршет, шведский стол","vi":"bữa tiệc buffet","fa":"بوفه","examples":[{"de":"Beim Frühstück gibt es ein großes Buffet mit vielen Speisen.","en":"At breakfast there's a large buffet with many dishes.","ru":"На завтраке большой шведский стол с множеством блюд.","vi":"Vào bữa sáng có tiệc buffet lớn với nhiều món ăn.","fa":"در وعده صبحانه یک بوفه بزرگ با غذاهای فراوان وجود دارد."},{"de":"Auf der Hochzeit stand ein reiches Buffet bereit.","en":"At the wedding a rich buffet was ready.","ru":"На свадьбе был приготовлен богатый фуршетный стол.","vi":"Tiệc buffet phong phú được phục vụ trong đám cưới.","fa":"یک بوفه غنی در مراسم عروسی موجود بود."}]},{"word":"das Bügeleisen","en":"iron (for clothes)","ru":"утюг","vi":"bàn ủi","fa":"آهن","examples":[{"de":"Pass auf, das Bügeleisen ist noch heiß!","en":"Be careful, the iron is still hot!","ru":"Осторожно, утюг ещё горячий!","vi":"Hãy cẩn thận, bàn ủi vẫn còn nóng!","fa":"مراقب باشید، اتو هنوز داغ است!"},{"de":"Mit diesem Bügeleisen werden die Hemden richtig glatt.","en":"With this iron the shirts come out really smooth.","ru":"С этим утюгом рубашки становятся по-настоящему гладкими.","vi":"Bàn ủi này sẽ làm cho áo sơ mi của bạn thật sự mịn màng.","fa":"این اتو پیراهن های شما را واقعا صاف می کند."},{"de":"Ich habe vergessen, das Bügeleisen auszuschalten.","en":"I forgot to turn off the iron.","ru":"Я забыл выключить утюг.","vi":"Tôi quên tắt bàn ủi.","fa":"فراموش کردم اتو را خاموش کنم."}]},{"word":"die Bühne","en":"stage","ru":"сцена","vi":"sân khấu","fa":"صحنه","examples":[{"de":"Der Sänger stand allein auf der Bühne.","en":"The singer stood alone on the stage.","ru":"Певец стоял один на сцене.","vi":"Ca sĩ đứng một mình trên sân khấu.","fa":"خواننده روی صحنه تنها بود."},{"de":"Die Schauspieler betraten die Bühne.","en":"The actors entered the stage.","ru":"Актёры вышли на сцену.","vi":"Các diễn viên bước vào sân khấu.","fa":"بازیگران وارد صحنه شدند."}]},{"word":"der Bundeskanzler","en":"federal chancellor","ru":"федеральный канцлер","vi":"thủ tướng liên bang","fa":"صدراعظم فدرال","examples":[{"de":"Der Bundeskanzler leitet die Regierung in Deutschland.","en":"The federal chancellor leads the government in Germany.","ru":"Федеральный канцлер возглавляет правительство Германии.","vi":"Thủ tướng đứng đầu chính phủ ở Đức.","fa":"صدراعظم در آلمان ریاست دولت را بر عهده دارد."},{"de":"Der Bundeskanzler traf sich mit dem französischen Präsidenten.","en":"The federal chancellor met with the French president.","ru":"Федеральный канцлер встретился с президентом Франции.","vi":"Thủ tướng gặp Tổng thống Pháp.","fa":"صدراعظم با رئیس جمهور فرانسه دیدار کرد."},{"de":"Wer wird der nächste Bundeskanzler?","en":"Who will be the next federal chancellor?","ru":"Кто станет следующим федеральным канцлером?","vi":"Ai sẽ là Thủ tướng tiếp theo?","fa":"صدراعظم بعدی چه کسی خواهد بود؟"}]},{"word":"der Bundestag","en":"the Bundestag (German federal parliament)","ru":"Бундестаг (парламент Германии)","vi":"Bundestag","fa":"بوندستاگ","examples":[{"de":"Der Bundestag tagt in Berlin im Reichstagsgebäude.","en":"The Bundestag sits in Berlin in the Reichstag building.","ru":"Бундестаг заседает в Берлине, в здании Рейхстага.","vi":"Bundestag họp ở Berlin trong tòa nhà Reichstag.","fa":"بوندستاگ در برلین در ساختمان رایشتاگ تشکیل جلسه می دهد."},{"de":"Im Bundestag sitzen Vertreter aus vielen Parteien.","en":"There are representatives from many parties in the Bundestag.","ru":"В Бундестаге сидят представители многих партий.","vi":"Đại diện của nhiều đảng ngồi trong Bundestag.","fa":"نمایندگان بسیاری از احزاب در بوندستاگ حضور دارند."},{"de":"Der Bundestag stimmt morgen über den Haushalt ab.","en":"The Bundestag votes on the budget tomorrow.","ru":"Завтра Бундестаг голосует по бюджету.","vi":"Hạ viện sẽ bỏ phiếu về ngân sách vào ngày mai.","fa":"بوندستاگ فردا درباره بودجه رای گیری می کند."}]},{"word":"das Bündnis","en":"alliance","ru":"союз, альянс","vi":"liên minh","fa":"اتحاد","examples":[{"de":"Die beiden Staaten schlossen ein militärisches Bündnis.","en":"The two states formed a military alliance.","ru":"Оба государства заключили военный союз.","vi":"Hai bang đã ký kết một liên minh quân sự.","fa":"دو کشور وارد یک اتحاد نظامی شدند."},{"de":"Das Bündnis hielt nur wenige Jahre.","en":"The alliance lasted only a few years.","ru":"Союз продержался лишь несколько лет.","vi":"Liên minh chỉ tồn tại được vài năm.","fa":"این اتحاد فقط چند سال به طول انجامید."},{"de":"Ein starkes Bündnis schützte das kleine Land.","en":"A strong alliance protected the small country.","ru":"Сильный союз защищал маленькую страну.","vi":"Một liên minh mạnh mẽ đã bảo vệ đất nước nhỏ bé.","fa":"یک اتحاد قوی از کشور کوچک محافظت می کرد."}]},{"word":"bunt","en":"colorful","ru":"разноцветный","vi":"đầy màu sắc","fa":"رنگارنگ","examples":[{"de":"Die Kinder malten ein buntes Bild.","en":"The children painted a colorful picture.","ru":"Дети нарисовали разноцветную картину.","vi":"Các em đã vẽ nên một bức tranh đầy màu sắc.","fa":"بچه ها نقاشی رنگارنگ کشیدند."},{"de":"Im Herbst sind die Blätter bunt.","en":"In autumn the leaves are colorful.","ru":"Осенью листья разноцветные.","vi":"Vào mùa thu, lá có nhiều màu sắc.","fa":"در پاییز برگها رنگارنگ هستند."}]},{"word":"die Burg","en":"castle","ru":"крепость, замок","vi":"lâu đài","fa":"قلعه","examples":[{"de":"Wir haben am Wochenende eine alte Burg besichtigt.","en":"We visited an old castle on the weekend.","ru":"В выходные мы осмотрели старый замок.","vi":"Chúng tôi đến thăm một lâu đài cổ vào cuối tuần.","fa":"آخر هفته از یک قلعه قدیمی بازدید کردیم."},{"de":"Die Burg steht hoch oben auf einem Berg.","en":"The castle stands high up on a mountain.","ru":"Замок стоит высоко на горе.","vi":"Lâu đài đứng cao trên một ngọn núi.","fa":"این قلعه بر فراز کوهی قرار دارد."}]},{"word":"der Bürger","en":"citizen","ru":"гражданин","vi":"công dân","fa":"شهروند","examples":[{"de":"Jeder Bürger hat das Recht zu wählen.","en":"Every citizen has the right to vote.","ru":"Каждый гражданин имеет право голосовать.","vi":"Mọi công dân đều có quyền bầu cử.","fa":"هر شهروندی حق رای دارد."},{"de":"Die Bürger der Stadt protestierten gegen den Plan.","en":"The citizens of the city protested against the plan.","ru":"Жители города протестовали против этого плана.","vi":"Người dân thành phố phản đối kế hoạch này.","fa":"شهروندان این شهر به این طرح اعتراض کردند."}]},{"word":"die Bürgerin","en":"citizen (female)","ru":"гражданка","vi":"công dân","fa":"شهروند","examples":[{"de":"Als Bürgerin dieses Landes darf sie wählen.","en":"As a citizen of this country she is allowed to vote.","ru":"Как гражданка этой страны она имеет право голосовать.","vi":"Là công dân của đất nước này, cô ấy có thể bỏ phiếu.","fa":"او به عنوان یک شهروند این کشور می تواند رای دهد."},{"de":"Jede Bürgerin hat das Recht auf freie Meinungsäußerung.","en":"Every citizen has the right to freedom of expression.","ru":"Каждая гражданка имеет право на свободу выражения мнения.","vi":"Mọi công dân đều có quyền tự do ngôn luận.","fa":"هر شهروندی حق آزادی بیان دارد."},{"de":"Die Bürgerin beschwerte sich beim Bürgermeister über den Lärm.","en":"The citizen complained to the mayor about the noise.","ru":"Гражданка пожаловалась мэру на шум.","vi":"Người dân phàn nàn với thị trưởng về tiếng ồn.","fa":"این شهروند به دلیل سر و صدا از شهردار شکایت کرد."}]},{"word":"die Bürgerinitiative","en":"citizens' initiative, grassroots campaign","ru":"гражданская инициатива","vi":"sáng kiến của công dân","fa":"ابتکار شهروندان","examples":[{"de":"Eine Bürgerinitiative kämpft gegen die neue Straße.","en":"A citizens' initiative is fighting against the new road.","ru":"Гражданская инициатива борется против новой дороги.","vi":"Một sáng kiến của người dân đang đấu tranh chống lại con đường mới.","fa":"یک ابتکار شهروندی در حال مبارزه با جاده جدید است."},{"de":"Die Bürgerinitiative sammelte tausende Unterschriften.","en":"The citizens' initiative collected thousands of signatures.","ru":"Гражданская инициатива собрала тысячи подписей.","vi":"Sáng kiến ​​của người dân đã thu thập được hàng nghìn chữ ký.","fa":"ابتکار شهروندان هزاران امضا جمع آوری کرد."},{"de":"In unserem Viertel gründeten die Nachbarn eine Bürgerinitiative.","en":"In our neighbourhood the residents founded a citizens' initiative.","ru":"В нашем районе соседи создали гражданскую инициативу.","vi":"Những người hàng xóm trong khu phố của chúng tôi đã thành lập một sáng kiến ​​của công dân.","fa":"همسایگان محله ما یک ابتکار شهروندی را تأسیس کردند."}]},{"word":"der Bürgermeister","en":"mayor","ru":"мэр, бургомистр","vi":"thị trưởng","fa":"شهردار","examples":[{"de":"Der Bürgermeister eröffnete das neue Schwimmbad.","en":"The mayor opened the new swimming pool.","ru":"Мэр открыл новый бассейн.","vi":"Thị trưởng đã mở bể bơi mới.","fa":"شهردار استخر جدید را افتتاح کرد."},{"de":"Unsere Stadt bekommt im Herbst einen neuen Bürgermeister.","en":"Our city is getting a new mayor in autumn.","ru":"Осенью в нашем городе будет новый мэр.","vi":"Thành phố của chúng ta sẽ có thị trưởng mới vào mùa thu.","fa":"شهر ما در پاییز شهردار جدیدی خواهد داشت."},{"de":"Die Bürgermeisterin setzt sich für mehr Grünflächen ein.","en":"The mayor is campaigning for more green spaces.","ru":"Мэр выступает за увеличение зелёных зон.","vi":"Thị trưởng cam kết có nhiều không gian xanh hơn.","fa":"شهردار متعهد به فضای سبز بیشتر است."}]},{"word":"das Büro","en":"office","ru":"офис","vi":"văn phòng","fa":"دفتر","examples":[{"de":"Ich arbeite von 9 bis 17 Uhr im Büro.","en":"I work in the office from 9 to 5.","ru":"Я работаю в офисе с 9 до 17 часов.","vi":"Tôi làm việc ở văn phòng từ 9 giờ sáng đến 5 giờ chiều.","fa":"من از ساعت 9 صبح تا 5 بعد از ظهر در دفتر کار می کنم."},{"de":"Ihr Büro liegt im dritten Stock.","en":"Her office is on the third floor.","ru":"Её офис находится на третьем этаже.","vi":"Văn phòng của cô ấy ở trên tầng ba.","fa":"دفتر او در طبقه سوم است."}]},{"word":"die Bürste","en":"brush","ru":"щётка","vi":"bàn chải","fa":"قلم مو","examples":[{"de":"Sie kämmt ihre Haare mit einer Bürste.","en":"She brushes her hair with a brush.","ru":"Она расчёсывает волосы щёткой.","vi":"Cô ấy chải tóc bằng lược.","fa":"موهایش را با برس شانه می کند."},{"de":"Mit dieser Bürste reinige ich meine Schuhe.","en":"I clean my shoes with this brush.","ru":"Этой щёткой я чищу свою обувь.","vi":"Tôi sử dụng bàn chải này để làm sạch giày của tôi.","fa":"من از این برس برای تمیز کردن کفش هایم استفاده می کنم."}]},{"word":"der Bus","en":"bus","ru":"автобус","vi":"xe buýt","fa":"اتوبوس","examples":[{"de":"Ich fahre jeden Tag mit dem Bus zur Arbeit.","en":"I take the bus to work every day.","ru":"Я каждый день езжу на автобусе на работу.","vi":"Tôi đi xe buýt đi làm hàng ngày.","fa":"من هر روز با اتوبوس سر کار می روم."},{"de":"Der Bus kommt in fünf Minuten.","en":"The bus arrives in five minutes.","ru":"Автобус приедет через пять минут.","vi":"Xe buýt sẽ đến trong năm phút nữa.","fa":"اتوبوس پنج دقیقه دیگر می آید."}]},{"word":"die Butter","en":"butter","ru":"масло (сливочное)","vi":"bơ","fa":"کره","examples":[{"de":"Ich streiche Butter auf mein Brot.","en":"I spread butter on my bread.","ru":"Я намазываю масло на хлеб.","vi":"Tôi phết bơ lên bánh mì của mình.","fa":"روی نانم کره زدم."},{"de":"Wir brauchen noch Butter zum Backen.","en":"We still need butter for baking.","ru":"Нам ещё нужно масло для выпечки.","vi":"Chúng ta vẫn cần bơ để nướng bánh.","fa":"هنوز برای پخت به کره نیاز داریم."}]},{"word":"das Café","en":"café","ru":"кафе","vi":"quán cà phê","fa":"کافه","examples":[{"de":"Wir treffen uns im Café um drei Uhr.","en":"We're meeting at the café at three o'clock.","ru":"Мы встречаемся в кафе в три часа.","vi":"Chúng ta sẽ gặp nhau ở quán cà phê lúc ba giờ.","fa":"ساعت سه در کافه همدیگر را می بینیم."},{"de":"Dieses Café serviert den besten Kuchen der Stadt.","en":"This café serves the best cake in the city.","ru":"Это кафе подаёт лучший торт в городе.","vi":"Quán cà phê này phục vụ bánh ngon nhất trong thị trấn.","fa":"این کافه بهترین کیک شهر را سرو می کند."}]},{"word":"die Cafeteria","en":"cafeteria","ru":"кафетерий, столовая","vi":"quán ăn tự phục vụ","fa":"کافه تریا","examples":[{"de":"In der Mittagspause essen wir in der Cafeteria.","en":"During lunch break we eat in the cafeteria.","ru":"В обеденный перерыв мы едим в кафетерии.","vi":"Trong giờ nghỉ trưa, chúng tôi ăn ở căng tin.","fa":"در زمان استراحت ناهار در کافه تریا غذا می خوریم."},{"de":"Die Cafeteria der Universität ist immer voll.","en":"The university cafeteria is always full.","ru":"Кафетерий университета всегда полон.","vi":"Căn tin của trường đại học luôn đầy ắp.","fa":"کافه تریا دانشگاه همیشه پر است."}]},{"word":"campen","en":"to camp","ru":"жить в палатке, ходить в поход с ночёвкой (кемпинговать)","vi":"cắm trại","fa":"کمپینگ","examples":[{"de":"Im Sommer campen wir oft am See.","en":"In summer we often camp by the lake.","ru":"Летом мы часто разбиваем лагерь у озера.","vi":"Vào mùa hè chúng tôi thường cắm trại ở hồ.","fa":"در تابستان اغلب در دریاچه چادر می زنیم."},{"de":"Wir haben am Wochenende in den Bergen gecampt.","en":"We camped in the mountains at the weekend.","ru":"На выходных мы жили в палатке в горах.","vi":"Chúng tôi cắm trại trên núi vào cuối tuần.","fa":"آخر هفته در کوه کمپ زدیم."},{"de":"Magst du lieber campen oder im Hotel wohnen?","en":"Do you prefer to camp or to stay in a hotel?","ru":"Ты предпочитаешь палатку или отель?","vi":"Bạn thích cắm trại hay ở khách sạn hơn?","fa":"کمپینگ را ترجیح می دهید یا اقامت در هتل؟"}]},{"word":"der Campingplatz","en":"campsite","ru":"кемпинг, площадка для кемпинга","vi":"khu cắm trại","fa":"محل کمپینگ","examples":[{"de":"Im Sommer fahren wir auf einen Campingplatz am See.","en":"In summer we go to a campsite by the lake.","ru":"Летом мы едем в кемпинг у озера.","vi":"Vào mùa hè chúng tôi đi cắm trại bên hồ.","fa":"در تابستان به یک کمپینگ در کنار دریاچه می رویم."},{"de":"Der Campingplatz ist sehr ruhig und sauber.","en":"The campsite is very quiet and clean.","ru":"Кемпинг очень тихий и чистый.","vi":"Khu cắm trại rất yên tĩnh và sạch sẽ.","fa":"کمپ بسیار آرام و تمیز است."},{"de":"Auf dem Campingplatz gibt es Duschen und einen Supermarkt.","en":"At the campsite there are showers and a supermarket.","ru":"В кемпинге есть душевые и супермаркет.","vi":"Có vòi sen và siêu thị tại khu cắm trại.","fa":"دوش و سوپرمارکت در محل کمپینگ وجود دارد."}]},{"word":"der Cappuccino","en":"cappuccino","ru":"капучино","vi":"cà phê cappuccino","fa":"کاپوچینو","examples":[{"de":"Zum Kuchen passt ein cremiger Cappuccino.","en":"A creamy cappuccino goes well with cake.","ru":"К пирогу подходит кремовый капучино.","vi":"Một cốc cappuccino kem rất hợp với bánh.","fa":"یک کاپوچینوی خامه ای به خوبی با کیک می آید."},{"de":"Der Cappuccino hat eine dicke Schicht Milchschaum.","en":"The cappuccino has a thick layer of milk foam.","ru":"У капучино толстый слой молочной пены.","vi":"Cappuccino có một lớp bọt sữa dày.","fa":"کاپوچینو لایه ضخیمی از کف شیر دارد."},{"de":"Sie bestellte einen Cappuccino mit Hafermilch.","en":"She ordered a cappuccino with oat milk.","ru":"Она заказала капучино на овсяном молоке.","vi":"Cô gọi một cốc cappuccino với sữa yến mạch.","fa":"او یک کاپوچینو با شیر جو سفارش داد."}]},{"word":"die Chance","en":"chance; opportunity","ru":"шанс","vi":"cơ hội","fa":"شانس","examples":[{"de":"Das ist deine Chance, den Job zu bekommen.","en":"This is your chance to get the job.","ru":"Это твой шанс получить эту работу.","vi":"Đây là cơ hội để bạn có được công việc.","fa":"این فرصت شماست تا شغل را بدست آورید."},{"de":"Er hat keine Chance mehr, das Spiel zu gewinnen.","en":"He no longer has a chance to win the game.","ru":"У него больше нет шанса выиграть игру.","vi":"Anh ta không còn cơ hội chiến thắng trong trò chơi nữa.","fa":"او دیگر شانسی برای بردن بازی ندارد."}]},{"word":"der Check-in","en":"check-in","ru":"регистрация (на рейс), чек-ин","vi":"việc đăng ký","fa":"ورود","examples":[{"de":"Der Check-in beginnt zwei Stunden vor dem Abflug.","en":"Check-in begins two hours before departure.","ru":"Регистрация начинается за два часа до вылета.","vi":"Việc nhận phòng bắt đầu hai giờ trước khi khởi hành.","fa":"ورود دو ساعت قبل از حرکت شروع می شود."},{"de":"Wir müssen rechtzeitig zum Check-in gehen.","en":"We have to go to check-in on time.","ru":"Нам нужно вовремя пройти на регистрацию.","vi":"Chúng tôi phải đến nhận phòng đúng giờ.","fa":"باید به موقع برای تحویل گرفتن برویم."},{"de":"Der Check-in im Hotel war sehr schnell.","en":"The check-in at the hotel was very quick.","ru":"Заселение в отеле прошло очень быстро.","vi":"Nhận phòng tại khách sạn rất nhanh chóng.","fa":"پذیرش در هتل بسیار سریع بود."}]},{"word":"der Chef","en":"boss","ru":"начальник, шеф","vi":"ông chủ","fa":"رئیس","examples":[{"de":"Mein Chef ist sehr streng, aber fair.","en":"My boss is very strict but fair.","ru":"Мой начальник очень строгий, но справедливый.","vi":"Sếp của tôi rất nghiêm khắc nhưng công bằng.","fa":"رئیس من بسیار سختگیر اما منصف است."},{"de":"Ich muss morgen früh mit meinem Chef sprechen.","en":"I have to talk to my boss tomorrow morning.","ru":"Мне нужно поговорить с начальником завтра утром.","vi":"Sáng mai tôi phải nói chuyện với sếp của tôi.","fa":"فردا صبح باید با رئیسم صحبت کنم."}]},{"word":"chic","en":"smart, stylish, chic","ru":"шикарный, элегантный, модный","vi":"sang trọng","fa":"شیک","examples":[{"de":"Du siehst heute Abend wirklich chic aus.","en":"You look really smart this evening.","ru":"Ты сегодня вечером выглядишь по-настоящему шикарно.","vi":"Tối nay trông bạn thật sang trọng.","fa":"امشب واقعا شیک به نظر میرسی"},{"de":"Sie trägt ein chices schwarzes Kleid.","en":"She is wearing a chic black dress.","ru":"На ней элегантное чёрное платье.","vi":"Cô ấy đang mặc một chiếc váy đen sang trọng.","fa":"او یک لباس مشکی شیک پوشیده است."},{"de":"Das ist ein sehr chices Restaurant im Zentrum.","en":"That is a very stylish restaurant in the centre.","ru":"Это очень стильный ресторан в центре.","vi":"Đây là một nhà hàng rất sang trọng ở trung tâm.","fa":"این یک رستوران بسیار شیک در مرکز است."}]},{"word":"chic/schick","en":"chic; stylish","ru":"шикарный, стильный","vi":"sang trọng/sang trọng","fa":"شیک / شیک","examples":[{"de":"Sie trägt heute ein sehr schickes Kleid.","en":"She's wearing a very chic dress today.","ru":"Сегодня она в очень стильном платье.","vi":"Hôm nay cô ấy mặc một chiếc váy rất sang trọng.","fa":"او امروز یک لباس بسیار شیک پوشیده است."},{"de":"Das neue Restaurant ist wirklich chic eingerichtet.","en":"The new restaurant is really chicly decorated.","ru":"Новый ресторан оформлен действительно шикарно.","vi":"Nhà hàng mới thực sự sang trọng.","fa":"رستوران جدید واقعا شیک است."}]},{"word":"die Chipkarte","en":"chip card, smart card","ru":"чип-карта, смарт-карта","vi":"thẻ chip","fa":"کارت تراشه","examples":[{"de":"Mit dieser Chipkarte kannst du die Tür öffnen.","en":"With this chip card you can open the door.","ru":"Этой чип-картой можно открыть дверь.","vi":"Bạn có thể mở cửa bằng thẻ chip này.","fa":"با این تراشه کارت می توانید در را باز کنید."},{"de":"Ich habe meine Chipkarte für die Bibliothek verloren.","en":"I lost my chip card for the library.","ru":"Я потерял свою чип-карту для библиотеки.","vi":"Tôi bị mất thẻ chip thư viện.","fa":"کارت چیپ کتابخانه ام را گم کردم."},{"de":"Die Chipkarte funktioniert auch in der Mensa.","en":"The chip card also works in the canteen.","ru":"Чип-карта работает и в столовой.","vi":"Thẻ chip cũng có tác dụng ở căng tin.","fa":"کارت چیپ نیز در کافه تریا کار می کند."}]},{"word":"der Choreograf","en":"choreographer","ru":"хореограф","vi":"biên đạo múa","fa":"طراح رقص","examples":[{"de":"Der Choreograf erklärte den Tänzern jeden Schritt.","en":"The choreographer explained every step to the dancers.","ru":"Хореограф объяснил танцорам каждый шаг.","vi":"Biên đạo múa giải thích từng bước cho các vũ công.","fa":"طراح رقص هر مرحله را برای رقصندگان توضیح داد."},{"de":"Ein bekannter Choreograf leitete die Proben.","en":"A famous choreographer led the rehearsals.","ru":"Репетициями руководил известный хореограф.","vi":"Một biên đạo múa nổi tiếng đã dẫn dắt buổi diễn tập.","fa":"یک طراح رقص سرشناس تمرینات را رهبری می کرد."},{"de":"Der Choreograf wollte mehr Ausdruck in den Bewegungen.","en":"The choreographer wanted more expression in the movements.","ru":"Хореограф хотел больше выразительности в движениях.","vi":"Biên đạo múa muốn thể hiện nhiều hơn trong các động tác.","fa":"طراح رقص خواستار بیان بیشتر در حرکات بود."}]},{"word":"die Choreografie","en":"choreography","ru":"хореография","vi":"vũ đạo","fa":"رقص","examples":[{"de":"Die Choreografie für das Stück war sehr anspruchsvoll.","en":"The choreography for the piece was very demanding.","ru":"Хореография этого номера была очень сложной.","vi":"Vũ đạo của tác phẩm rất khắt khe.","fa":"طراحی رقص برای قطعه بسیار سخت بود."},{"de":"Sie hat die ganze Choreografie selbst entwickelt.","en":"She developed the entire choreography herself.","ru":"Всю хореографию она придумала сама.","vi":"Cô ấy tự mình phát triển tất cả các vũ đạo.","fa":"او تمام طراحی های رقص را خودش توسعه داد."},{"de":"Wir mussten die Choreografie mehrmals wiederholen.","en":"We had to repeat the choreography several times.","ru":"Нам пришлось несколько раз повторять хореографию.","vi":"Chúng tôi đã phải lặp lại vũ đạo nhiều lần.","fa":"مجبور شدیم رقص را چندین بار تکرار کنیم."}]},{"word":"die Cloud","en":"cloud (storage)","ru":"облако (облачное хранилище)","vi":"đám mây","fa":"ابر","examples":[{"de":"Ich speichere meine Fotos in der Cloud.","en":"I store my photos in the cloud.","ru":"Я храню свои фотографии в облаке.","vi":"Tôi lưu trữ ảnh của mình trên đám mây.","fa":"من عکس هایم را در فضای ابری ذخیره می کنم."},{"de":"Die Dateien in der Cloud sind von überall erreichbar.","en":"The files in the cloud are accessible from anywhere.","ru":"Файлы в облаке доступны отовсюду.","vi":"Các tập tin trong đám mây có thể được truy cập từ bất cứ đâu.","fa":"فایل های موجود در فضای ابری از هر جایی قابل دسترسی هستند."},{"de":"Ohne Internet komme ich nicht an die Cloud.","en":"Without internet I can't reach the cloud.","ru":"Без интернета я не могу попасть в облако.","vi":"Không có internet tôi không thể truy cập vào đám mây.","fa":"بدون اینترنت نمی توانم به ابر دسترسی داشته باشم."}]},{"word":"der Code","en":"code (source code, or a numeric/access code)","ru":"код (исходный код либо цифровой/кодовый ключ)","vi":"mã","fa":"کد","examples":[{"de":"Der Code ist sauber geschrieben und leicht zu lesen.","en":"The code is cleanly written and easy to read.","ru":"Код написан чисто и легко читается.","vi":"Mã được viết rõ ràng và dễ đọc.","fa":"کد کاملاً نوشته شده است و به راحتی قابل خواندن است."},{"de":"Du brauchst den richtigen Code, um die Tür zu öffnen.","en":"You need the right code to open the door.","ru":"Тебе нужен правильный код, чтобы открыть дверь.","vi":"Bạn cần mã chính xác để mở cửa.","fa":"برای باز کردن در به کد صحیح نیاز دارید."},{"de":"Bitte gib den vierstelligen Code aus der SMS ein.","en":"Please enter the four-digit code from the text message.","ru":"Пожалуйста, введи четырёхзначный код из СМС.","vi":"Vui lòng nhập mã gồm bốn chữ số từ SMS.","fa":"لطفا کد چهار رقمی را از پیامک وارد کنید."}]},{"word":"der Coiffeur","en":"hairdresser","ru":"парикмахер","vi":"thợ làm tóc","fa":"آرایشگاه","examples":[{"de":"Ich habe morgen einen Termin beim Coiffeur.","en":"I have an appointment at the hairdresser's tomorrow.","ru":"У меня завтра запись к парикмахеру.","vi":"Tôi có cuộc hẹn với thợ làm tóc vào ngày mai.","fa":"فردا با آرایشگر وقت دارم."},{"de":"Der Coiffeur hat mir die Haare kurz geschnitten.","en":"The hairdresser cut my hair short.","ru":"Парикмахер коротко подстриг мне волосы.","vi":"Thợ làm tóc đã cắt tóc ngắn cho tôi.","fa":"آرایشگر موهایم را کوتاه کرد."}]},{"word":"die Coiffeuse","en":"hairdresser (female, Swiss usage)","ru":"парикмахер (жен., швейцарское употребление)","vi":"thợ làm tóc","fa":"آرایشگاه","examples":[{"de":"Die Coiffeuse hat sehr geschickte Hände.","en":"The hairdresser has very skilful hands.","ru":"У парикмахера очень умелые руки.","vi":"Người thợ làm tóc có bàn tay rất khéo léo.","fa":"آرایشگر دستان بسیار ماهری دارد."},{"de":"Meine Coiffeuse arbeitet seit zehn Jahren im Salon.","en":"My hairdresser has worked at the salon for ten years.","ru":"Моя парикмахер работает в салоне уже десять лет.","vi":"Thợ làm tóc của tôi đã làm việc ở tiệm được mười năm.","fa":"آرایشگر من ده سال است که در سالن کار می کند."},{"de":"Die Coiffeuse beriet mich bei der Wahl der Farbe.","en":"The hairdresser advised me on choosing the colour.","ru":"Парикмахер помогла мне с выбором цвета.","vi":"Thợ làm tóc tư vấn cho tôi về việc lựa chọn màu sắc.","fa":"آرایشگر در مورد انتخاب رنگ به من توصیه کرد."}]},{"word":"die Couch","en":"couch; sofa","ru":"диван","vi":"chiếc ghế dài","fa":"کاناپه","examples":[{"de":"Am Abend liegen wir gerne auf der Couch und schauen fern.","en":"In the evening we like to lie on the couch and watch TV.","ru":"Вечером мы любим лежать на диване и смотреть телевизор.","vi":"Vào buổi tối, chúng tôi thích nằm trên ghế dài và xem TV.","fa":"عصرها دوست داریم روی مبل دراز بکشیم و تلویزیون تماشا کنیم."},{"de":"Die neue Couch im Wohnzimmer ist sehr bequem.","en":"The new couch in the living room is very comfortable.","ru":"Новый диван в гостиной очень удобный.","vi":"Chiếc ghế dài mới trong phòng khách rất thoải mái.","fa":"کاناپه جدید در اتاق نشیمن بسیار راحت است."}]},{"word":"der Cousin","en":"cousin","ru":"двоюродный брат","vi":"anh họ","fa":"پسر عمو","examples":[{"de":"Mein Cousin wohnt in Berlin.","en":"My cousin lives in Berlin.","ru":"Мой двоюродный брат живёт в Берлине.","vi":"Anh họ của tôi sống ở Berlin.","fa":"پسر عموی من در برلین زندگی می کند."},{"de":"Am Wochenende besuche ich meinen Cousin.","en":"On the weekend I'm visiting my cousin.","ru":"В выходные я навещу своего двоюродного брата.","vi":"Vào cuối tuần tôi đến thăm anh họ của tôi.","fa":"آخر هفته به دیدن پسر عمویم می‌روم."}]},{"word":"das Couvert","en":"envelope","ru":"конверт","vi":"phong bì","fa":"پاکت نامه","examples":[{"de":"Ich stecke den Brief in ein Couvert.","en":"I put the letter in an envelope.","ru":"Я кладу письмо в конверт.","vi":"Tôi bỏ lá thư vào phong bì.","fa":"نامه را در یک پاکت گذاشتم."},{"de":"Auf dem Couvert steht die Adresse des Empfängers.","en":"The recipient's address is on the envelope.","ru":"На конверте указан адрес получателя.","vi":"Địa chỉ người nhận được ghi trên phong bì.","fa":"آدرس گیرنده روی پاکت نوشته شده است."}]},{"word":"die Creme","en":"cream","ru":"крем","vi":"kem","fa":"کرم","examples":[{"de":"Sie trägt jeden Abend eine Creme für ihre Haut auf.","en":"She applies a cream for her skin every evening.","ru":"Она каждый вечер наносит крем для кожи.","vi":"Cô ấy thoa kem lên da vào mỗi buổi tối.","fa":"او هر روز غروب یک کرم روی پوستش می‌مالد."},{"de":"Nach dem Sonnenbad benutze ich eine kühlende Creme.","en":"After sunbathing I use a cooling cream.","ru":"После загара я использую охлаждающий крем.","vi":"Sau khi tắm nắng tôi sử dụng kem làm mát.","fa":"بعد از آفتاب گرفتن از کرم خنک کننده استفاده می کنم."}]},{"word":"da","en":"there; since/because","ru":"там; так как","vi":"ở đó","fa":"وجود دارد","examples":[{"de":"Da drüben steht mein Auto.","en":"My car is over there.","ru":"Там стоит моя машина.","vi":"Xe của tôi ở đằng kia.","fa":"ماشین من اونجاست"},{"de":"Da es regnet, bleiben wir zu Hause.","en":"Since it's raining, we're staying home.","ru":"Так как идёт дождь, мы останемся дома.","vi":"Vì trời mưa nên chúng tôi ở nhà.","fa":"از آنجایی که باران می بارد، ما در خانه می مانیم."}]},{"word":"Da bin ich anderer Meinung","en":"I'm of a different opinion (disagreement)","ru":"Тут я другого мнения (несогласие)","vi":"Tôi có quan điểm khác","fa":"من نظر دیگری دارم","examples":[{"de":"Da bin ich anderer Meinung als du.","en":"I'm of a different opinion than you.","ru":"Тут я другого мнения, чем ты.","vi":"Tôi có quan điểm khác với bạn.","fa":"من نظر متفاوتی با شما دارم"}]},{"word":"Da hast du recht","en":"You're right about that (agreement)","ru":"Тут ты прав (согласие)","vi":"Bạn nói đúng về điều đó","fa":"در مورد آن حق با شماست","examples":[{"de":"Da hast du recht, das habe ich nicht bedacht.","en":"You're right about that, I hadn't considered it.","ru":"Тут ты прав, я об этом не подумал.","vi":"Bạn nói đúng, tôi đã không xem xét điều đó.","fa":"حق با شماست، من این را در نظر نگرفتم."}]},{"word":"Da muss ich dir leider widersprechen","en":"I'm afraid I have to disagree with you (disagreement)","ru":"Тут я, к сожалению, вынужден возразить (несогласие)","vi":"Tôi e rằng tôi phải không đồng ý với bạn","fa":"می ترسم مجبور باشم با شما مخالفت کنم","examples":[{"de":"Da muss ich dir leider widersprechen, das ist nicht erlaubt.","en":"I'm afraid I have to disagree, that's not allowed.","ru":"Тут я, к сожалению, вынужден возразить, это запрещено.","vi":"Thật không may, tôi phải không đồng ý với bạn, điều đó không được phép.","fa":"متأسفانه باید با شما مخالفت کنم، این مجاز نیست."}]},{"word":"Da stimme ich dir zu","en":"I agree with you (agreement)","ru":"Тут я с тобой согласен (согласие)","vi":"tôi đồng ý với bạn","fa":"من با شما موافقم","examples":[{"de":"Da stimme ich dir völlig zu.","en":"I completely agree with you.","ru":"Тут я с тобой полностью согласен.","vi":"Tôi hoàn toàn đồng ý với bạn.","fa":"من کاملا با شما موافقم"}]},{"word":"dabei","en":"with it; while doing so","ru":"при этом","vi":"ở đó","fa":"وجود دارد","examples":[{"de":"Ich koche gern und höre dabei Musik.","en":"I like to cook and listen to music while doing so.","ru":"Я люблю готовить и при этом слушать музыку.","vi":"Tôi thích nấu ăn và nghe nhạc.","fa":"من آشپزی و گوش دادن به موسیقی را دوست دارم."},{"de":"Bist du am Samstag auch dabei?","en":"Are you joining in on Saturday too?","ru":"Ты тоже будешь участвовать в субботу?","vi":"Bạn cũng ở đó vào thứ bảy phải không?","fa":"شنبه هم هستی؟"}]},{"word":"das Dach","en":"roof","ru":"крыша","vi":"mái nhà","fa":"سقف","examples":[{"de":"Nach dem Sturm mussten sie das Dach reparieren.","en":"After the storm they had to repair the roof.","ru":"После шторма им пришлось починить крышу.","vi":"Sau cơn bão họ phải sửa lại mái nhà.","fa":"پس از طوفان مجبور شدند سقف را تعمیر کنند."},{"de":"Auf dem Dach unseres Hauses sind Solarzellen.","en":"There are solar panels on the roof of our house.","ru":"На крыше нашего дома есть солнечные батареи.","vi":"Có pin mặt trời trên mái nhà của chúng tôi.","fa":"در پشت بام خانه ما سلول های خورشیدی وجود دارد."}]},{"word":"dafür","en":"for it; in favor of it","ru":"за это","vi":"vì điều đó","fa":"برای آن","examples":[{"de":"Ich bin dafür, dass wir früher losfahren.","en":"I'm in favor of us leaving earlier.","ru":"Я за то, чтобы мы выехали пораньше.","vi":"Tôi ủng hộ việc rời đi sớm hơn.","fa":"من طرفدار زودتر رفتن هستم."},{"de":"Er hat hart gearbeitet, und dafür wurde er belohnt.","en":"He worked hard, and for that he was rewarded.","ru":"Он много работал, и за это его вознаградили.","vi":"Anh ấy đã làm việc chăm chỉ và được khen thưởng vì điều đó.","fa":"او سخت کار کرد و برای آن پاداش گرفت."}]},{"word":"dagegen","en":"against it","ru":"против этого","vi":"chống lại nó","fa":"در برابر آن","examples":[{"de":"Ich bin dagegen, dass wir das Projekt abbrechen.","en":"I'm against us cancelling the project.","ru":"Я против того, чтобы мы прекратили проект.","vi":"Tôi phản đối việc hủy bỏ dự án.","fa":"من مخالف لغو پروژه هستم."},{"de":"Hast du etwas dagegen, wenn ich das Fenster öffne?","en":"Do you mind if I open the window?","ru":"Ты не против, если я открою окно?","vi":"Bạn có phiền nếu tôi mở cửa sổ không?","fa":"آیا اشکالی ندارد که پنجره را باز کنم؟"}]},{"word":"daher","en":"therefore","ru":"поэтому","vi":"do đó","fa":"بنابراین","examples":[{"de":"Es regnet stark, daher bleibe ich lieber zu Hause.","en":"It's raining heavily, therefore I'd rather stay home.","ru":"Идёт сильный дождь, поэтому я лучше останусь дома.","vi":"Trời đang mưa to nên tôi thà ở nhà còn hơn.","fa":"باران شدیدی می بارد، پس ترجیح می دهم در خانه بمانم."},{"de":"Er kommt aus Wien, daher spricht er sehr gut Deutsch.","en":"He's from Vienna, that's why he speaks German very well.","ru":"Он из Вены, поэтому он очень хорошо говорит по-немецки.","vi":"Anh ấy đến từ Vienna nên nói tiếng Đức rất tốt.","fa":"او اهل وین است، بنابراین آلمانی را خیلی خوب صحبت می کند."}]},{"word":"dahin","en":"there; to that place","ru":"туда","vi":"ở đó","fa":"وجود دارد","examples":[{"de":"Wir fahren morgen dahin, wo wir letztes Jahr Urlaub gemacht haben.","en":"Tomorrow we're going there where we vacationed last year.","ru":"Завтра мы поедем туда, где отдыхали в прошлом году.","vi":"Ngày mai chúng ta sẽ đi đến nơi chúng ta đã đi nghỉ năm ngoái.","fa":"فردا میریم جایی که پارسال تعطیلات داشتیم."},{"de":"Bis dahin habe ich hoffentlich alles fertig.","en":"By then I'll hopefully have everything ready.","ru":"К тому времени я, надеюсь, всё закончу.","vi":"Hy vọng đến lúc đó tôi sẽ làm xong mọi việc.","fa":"امیدوارم تا آن زمان همه چیز تمام شده باشد."}]},{"word":"damals","en":"back then; at that time","ru":"тогда","vi":"hồi đó","fa":"آن زمان","examples":[{"de":"Damals wohnten wir noch in einem kleinen Dorf.","en":"Back then we still lived in a small village.","ru":"Тогда мы ещё жили в маленькой деревне.","vi":"Lúc đó chúng tôi vẫn sống ở một ngôi làng nhỏ.","fa":"در آن زمان ما هنوز در یک روستای کوچک زندگی می کردیم."},{"de":"Das Leben war damals viel einfacher.","en":"Life was much simpler back then.","ru":"Жизнь тогда была намного проще.","vi":"Cuộc sống hồi đó đơn giản hơn nhiều.","fa":"در آن زمان زندگی بسیار ساده تر بود."}]},{"word":"die Dame","en":"lady","ru":"дама","vi":"quý cô","fa":"خانم","examples":[{"de":"Die ältere Dame setzte sich neben mich in den Bus.","en":"The elderly lady sat down next to me on the bus.","ru":"Пожилая дама села рядом со мной в автобусе.","vi":"Người phụ nữ lớn tuổi ngồi cạnh tôi trên xe buýt.","fa":"خانم بزرگتر در اتوبوس کنار من نشست."},{"de":"Meine Damen und Herren, herzlich willkommen!","en":"Ladies and gentlemen, welcome!","ru":"Дамы и господа, добро пожаловать!","vi":"Thưa quý vị, xin chào mừng!","fa":"خانم ها و آقایان، خوش آمدید!"}]},{"word":"damit","en":"with it; so that","ru":"с этим; чтобы","vi":"với điều đó","fa":"با آن","examples":[{"de":"Ich habe einen Regenschirm, damit kann ich trocken bleiben.","en":"I have an umbrella, with it I can stay dry.","ru":"У меня есть зонт, с ним я могу остаться сухим.","vi":"Tôi có một chiếc ô để tôi có thể khô ráo.","fa":"من یک چتر دارم تا بتوانم خشک بمانم."},{"de":"Sie spricht langsam, damit alle sie verstehen.","en":"She speaks slowly so that everyone understands her.","ru":"Она говорит медленно, чтобы все её понимали.","vi":"Cô nói chậm để mọi người có thể hiểu được.","fa":"آهسته صحبت می کند تا همه او را بفهمند."}]},{"word":"danach","en":"after that; afterwards","ru":"после этого","vi":"sau đó","fa":"پس از آن","examples":[{"de":"Wir essen zu Mittag und gehen danach spazieren.","en":"We'll have lunch and go for a walk afterwards.","ru":"Мы пообедаем, а после этого пойдём гулять.","vi":"Chúng tôi ăn trưa và sau đó đi dạo.","fa":"ناهار می خوریم و بعد پیاده روی می کنیم."},{"de":"Zuerst die Hausaufgaben, danach kannst du spielen.","en":"First the homework, afterwards you can play.","ru":"Сначала домашнее задание, потом можешь играть.","vi":"Làm bài tập về nhà trước, sau đó mới có thể chơi.","fa":"اول تکالیف، بعد می توانید بازی کنید."}]},{"word":"daneben","en":"next to it; beside it","ru":"рядом с этим","vi":"bên cạnh nó","fa":"در کنار آن","examples":[{"de":"Das Sofa steht am Fenster, und daneben ist ein kleiner Tisch.","en":"The sofa is by the window, and next to it is a small table.","ru":"Диван стоит у окна, а рядом с ним стоит маленький столик.","vi":"Ghế sofa đặt cạnh cửa sổ và có một chiếc bàn nhỏ bên cạnh.","fa":"مبل کنار پنجره است و یک میز کوچک کنار آن قرار دارد."},{"de":"Die Kirche und das Rathaus daneben sind sehr alt.","en":"The church and the town hall next to it are very old.","ru":"Церковь и ратуша рядом с ней очень старые.","vi":"Nhà thờ và tòa thị chính bên cạnh rất cũ.","fa":"کلیسا و تالار شهر در کنار آن بسیار قدیمی هستند."}]},{"word":"dankbar","en":"grateful, thankful","ru":"благодарный, признательный","vi":"biết ơn","fa":"سپاسگزار","examples":[{"de":"Ich bin dir sehr dankbar für deine Hilfe.","en":"I'm very grateful to you for your help.","ru":"Я тебе очень благодарен за помощь.","vi":"Tôi rất biết ơn sự giúp đỡ của bạn.","fa":"من از کمک شما بسیار سپاسگزارم."},{"de":"Sie war dankbar, dass alles gut ausgegangen war.","en":"She was thankful that everything had turned out well.","ru":"Она была благодарна, что всё хорошо закончилось.","vi":"Cô biết ơn vì mọi chuyện đã diễn ra tốt đẹp.","fa":"او از اینکه همه چیز خوب پیش رفته بود سپاسگزار بود."},{"de":"Für jede Unterstützung sind wir dankbar.","en":"We are grateful for any support.","ru":"Мы благодарны за любую поддержку.","vi":"Chúng tôi rất biết ơn sự hỗ trợ nào.","fa":"ما از هر گونه حمایتی سپاسگزاریم."}]},{"word":"danken","en":"to thank","ru":"благодарить","vi":"cảm ơn bạn","fa":"متشکرم","examples":[{"de":"Ich möchte dir für deine Hilfe danken.","en":"I would like to thank you for your help.","ru":"Я хочу поблагодарить тебя за помощь.","vi":"Tôi muốn cảm ơn sự giúp đỡ của bạn.","fa":"می خواهم از کمک شما تشکر کنم."},{"de":"Er dankte allen Gästen für ihr Kommen.","en":"He thanked all the guests for coming.","ru":"Он поблагодарил всех гостей за то, что пришли.","vi":"Ông cảm ơn tất cả các vị khách đã đến.","fa":"او از حضور همه مهمانان تشکر کرد."}]},{"word":"dann","en":"then","ru":"тогда, потом","vi":"sau đó","fa":"سپس","examples":[{"de":"Wir essen jetzt, und dann gehen wir ins Kino.","en":"We'll eat now, and then we'll go to the movies.","ru":"Мы сейчас поедим, а потом пойдём в кино.","vi":"Chúng ta sẽ ăn bây giờ và sau đó chúng ta sẽ đi xem phim.","fa":"حالا میخوریم و بعد میرویم سینما."},{"de":"Wenn du fertig bist, dann ruf mich an.","en":"When you're done, then call me.","ru":"Когда закончишь, тогда позвони мне.","vi":"Khi nào xong hãy gọi cho tôi.","fa":"وقتی کارتان تمام شد، با من تماس بگیرید."}]},{"word":"Dann komme ich zu …","en":"Then I'll come to … (structuring)","ru":"Затем я перейду к … (структура)","vi":"Sau đó tôi sẽ tới…","fa":"بعد میام به…","examples":[{"de":"Dann komme ich zu einem wichtigen Punkt.","en":"Then I'll come to an important point.","ru":"Затем я перейду к важному пункту.","vi":"Sau đó tôi đến một điểm quan trọng.","fa":"سپس به یک نکته مهم می رسم."}]},{"word":"darstellen","en":"to depict; to represent","ru":"изображать, представлять","vi":"đại diện","fa":"نمایندگی کند","examples":[{"de":"Das Gemälde stellt eine Landschaft in den Alpen dar.","en":"The painting depicts a landscape in the Alps.","ru":"Картина изображает пейзаж в Альпах.","vi":"Bức tranh mô tả phong cảnh ở dãy Alps.","fa":"این نقاشی منظره ای را در کوه های آلپ به تصویر می کشد."},{"de":"Er stellt in seinem Vortrag die wichtigsten Ergebnisse dar.","en":"He presents the most important results in his talk.","ru":"В своём докладе он представляет самые важные результаты.","vi":"Ông trình bày những kết quả quan trọng nhất trong bài giảng của mình.","fa":"او مهمترین نتایج را در سخنرانی خود ارائه می کند."}]},{"word":"die Darstellung","en":"depiction, presentation","ru":"изображение, представление, изложение","vi":"sự đại diện","fa":"نمایندگی","examples":[{"de":"Die Darstellung der Zahlen in der Grafik ist klar.","en":"The depiction of the figures in the chart is clear.","ru":"Представление данных на диаграмме понятное.","vi":"Sự thể hiện của các con số trong đồ họa là rõ ràng.","fa":"نمایش اعداد در نمودار واضح است."},{"de":"Seine Darstellung der Ereignisse war sehr genau.","en":"His account of the events was very precise.","ru":"Его изложение событий было очень точным.","vi":"Lời tường thuật của ông về các sự kiện rất chính xác.","fa":"گزارش او از وقایع بسیار دقیق بود."},{"de":"Die Darstellung im Buch hat mir gut gefallen.","en":"I liked the presentation in the book.","ru":"Мне понравилось изложение в книге.","vi":"Tôi thích cách trình bày trong cuốn sách.","fa":"من از ارائه در کتاب خوشم آمد."}]},{"word":"das","en":"the (neuter); that, this; which","ru":"этот, это (средний род); то; который","vi":"đó","fa":"که","examples":[{"de":"Das Buch liegt auf dem Tisch.","en":"The book is lying on the table.","ru":"Книга лежит на столе.","vi":"Cuốn sách ở trên bàn.","fa":"کتاب روی میز است."},{"de":"Das ist meine beste Freundin.","en":"This is my best friend.","ru":"Это моя лучшая подруга.","vi":"Đây là người bạn tốt nhất của tôi.","fa":"این بهترین دوست من است."},{"de":"Das Kind, das dort spielt, ist mein Sohn.","en":"The child who is playing there is my son.","ru":"Ребёнок, который там играет, — мой сын.","vi":"Đứa trẻ đang chơi ở đó là con trai tôi.","fa":"بچه ای که آنجا بازی می کند پسر من است."}]},{"word":"das/der (Schlag-)Obers","en":"(whipped) cream (Austrian)","ru":"(взбитые) сливки (австр.)","vi":"kem (đánh bông)","fa":"خامه ( فرم گرفته )","examples":[{"de":"Ich hätte gern einen Kaffee mit Schlagobers.","en":"I'd like a coffee with whipped cream.","ru":"Я хотел бы кофе со взбитыми сливками.","vi":"Tôi muốn một ly cà phê với kem tươi.","fa":"من یک قهوه با خامه می خواهم."},{"de":"Auf dem Kuchen ist eine große Portion Obers.","en":"There's a large portion of cream on the cake.","ru":"На торте большая порция сливок.","vi":"Có một phần lớn kem trên bánh.","fa":"روی کیک مقدار زیادی خامه وجود دارد."}]},{"word":"das/der Zvieri/Znüni","en":"mid-morning/afternoon snack (Swiss German)","ru":"перекус (швейц. — второй завтрак/полдник)","vi":"bữa ăn nhẹ/bữa trưa","fa":"میان وعده/ناهار","examples":[{"de":"Die Kinder essen in der Schule ihr Znüni.","en":"The children eat their morning snack at school.","ru":"Дети едят свой перекус в школе.","vi":"Các em ăn trưa tại trường.","fa":"بچه ها ناهار خود را در مدرسه می خورند."},{"de":"Zum Zvieri gibt es heute einen Apfel und ein Brot.","en":"For the afternoon snack today there is an apple and bread.","ru":"На полдник сегодня яблоко и хлеб.","vi":"Hôm nay chúng tôi có một quả táo và bánh mì cho bữa ăn nhẹ.","fa":"امروز یک سیب و نان برای میان وعده داریم."}]},{"word":"dass","en":"that (conjunction)","ru":"что","vi":"đó","fa":"که","examples":[{"de":"Ich glaube, dass er recht hat.","en":"I believe that he is right.","ru":"Я думаю, что он прав.","vi":"Tôi nghĩ anh ấy đúng.","fa":"من فکر می کنم حق با اوست."},{"de":"Sie hofft, dass es morgen nicht regnet.","en":"She hopes that it won't rain tomorrow.","ru":"Она надеется, что завтра не будет дождя.","vi":"Cô hy vọng ngày mai trời không mưa.","fa":"او امیدوار است فردا باران نبارد."}]},{"word":"dasselbe","en":"the same (neuter)","ru":"то же самое (средний род)","vi":"giống nhau","fa":"همان","examples":[{"de":"Wir haben dasselbe Auto gekauft.","en":"We bought the same car.","ru":"Мы купили одну и ту же машину.","vi":"Chúng tôi đã mua cùng một chiếc xe.","fa":"ما همین ماشین را خریدیم."},{"de":"Ich nehme dasselbe wie du.","en":"I'll have the same as you.","ru":"Я возьму то же, что и ты.","vi":"Tôi cũng làm như bạn.","fa":"من هم مثل شما قبول دارم"},{"de":"Das ist immer wieder dasselbe Problem.","en":"It's always the same problem again.","ru":"Это снова и снова одна и та же проблема.","vi":"Đó là cùng một vấn đề lặp đi lặp lại.","fa":"بارها و بارها همین مشکل وجود دارد."}]},{"word":"die Datei","en":"file (computer)","ru":"файл","vi":"tập tin","fa":"فایل","examples":[{"de":"Ich habe die Datei versehentlich gelöscht.","en":"I accidentally deleted the file.","ru":"Я случайно удалил файл.","vi":"Tôi vô tình xóa tập tin.","fa":"من تصادفا فایل رو پاک کردم"},{"de":"Kannst du mir diese Datei per E-Mail schicken?","en":"Can you send me this file by email?","ru":"Можешь отправить мне этот файл по электронной почте?","vi":"Bạn có thể gửi email cho tôi tập tin này?","fa":"میشه این فایل رو برام ایمیل کنید؟"}]},{"word":"die Daten","en":"data (plural of Datum)","ru":"данные (мн. ч.)","vi":"dữ liệu","fa":"داده ها","examples":[{"de":"Bevor wir das Modell trainieren, müssen wir die Daten bereinigen.","en":"Before we train the model, we have to clean the data.","ru":"Прежде чем обучать модель, нужно очистить данные.","vi":"Trước khi huấn luyện mô hình, chúng ta cần làm sạch dữ liệu.","fa":"قبل از آموزش مدل، باید داده ها را تمیز کنیم."},{"de":"Die Daten zeigen einen klaren Anstieg im letzten Quartal.","en":"The data shows a clear increase in the last quarter.","ru":"Данные показывают явный рост в последнем квартале.","vi":"Dữ liệu cho thấy sự gia tăng rõ ràng trong quý vừa qua.","fa":"داده ها نشان دهنده افزایش واضح در سه ماهه گذشته است."},{"de":"Persönliche Daten müssen besonders gut geschützt werden.","en":"Personal data has to be especially well protected.","ru":"Персональные данные нужно защищать особенно тщательно.","vi":"Dữ liệu cá nhân phải được bảo vệ đặc biệt tốt.","fa":"داده های شخصی باید به خوبی محافظت شوند."}]},{"word":"die Daten (Plural)","en":"data","ru":"данные","vi":"dữ liệu (số nhiều)","fa":"داده ها (جمع)","examples":[{"de":"Die persönlichen Daten werden vertraulich behandelt.","en":"Personal data is treated confidentially.","ru":"Личные данные обрабатываются конфиденциально.","vi":"Dữ liệu cá nhân sẽ được xử lý bí mật.","fa":"با داده های شخصی محرمانه رفتار خواهد شد."},{"de":"Wir müssen die Daten noch einmal überprüfen.","en":"We need to check the data once more.","ru":"Нам нужно ещё раз проверить данные.","vi":"Chúng ta cần kiểm tra lại dữ liệu.","fa":"باید دوباره داده ها را بررسی کنیم."}]},{"word":"die Datenauswertung","en":"data analysis, data evaluation","ru":"анализ данных, обработка данных","vi":"đánh giá dữ liệu","fa":"ارزیابی داده ها","examples":[{"de":"Die Datenauswertung dauerte mehrere Wochen.","en":"The data analysis took several weeks.","ru":"Анализ данных длился несколько недель.","vi":"Việc phân tích dữ liệu mất vài tuần.","fa":"تجزیه و تحلیل داده ها چند هفته طول کشید."},{"de":"Für die Datenauswertung nutzen wir spezielle Software.","en":"For the data analysis we use special software.","ru":"Для анализа данных мы используем специальное программное обеспечение.","vi":"Chúng tôi sử dụng phần mềm đặc biệt để đánh giá dữ liệu.","fa":"برای ارزیابی داده ها از نرم افزار خاصی استفاده می کنیم."},{"de":"Die Datenauswertung zeigte einen klaren Trend.","en":"The data analysis showed a clear trend.","ru":"Анализ данных показал чёткую тенденцию.","vi":"Phân tích dữ liệu cho thấy một xu hướng rõ ràng.","fa":"تجزیه و تحلیل داده ها روند واضحی را نشان داد."}]},{"word":"die Datenerhebung","en":"data collection","ru":"сбор данных","vi":"việc thu thập dữ liệu","fa":"جمع آوری داده ها","examples":[{"de":"Vor der Analyse steht die Datenerhebung.","en":"Data collection comes before the analysis.","ru":"Перед анализом идёт сбор данных.","vi":"Trước khi phân tích là thu thập dữ liệu.","fa":"قبل از تجزیه و تحلیل، جمع آوری داده ها می آید."},{"de":"Die Datenerhebung erfolgt durch eine Umfrage.","en":"The data collection is carried out by a survey.","ru":"Сбор данных проводится с помощью опроса.","vi":"Dữ liệu được thu thập thông qua một cuộc khảo sát.","fa":"داده ها از طریق نظرسنجی جمع آوری می شود."},{"de":"Bei der Datenerhebung muss man genau arbeiten.","en":"You have to work precisely during data collection.","ru":"При сборе данных нужно работать точно.","vi":"Bạn phải chính xác khi thu thập dữ liệu.","fa":"هنگام جمع آوری داده ها باید دقیق باشید."}]},{"word":"die Datenmenge","en":"amount of data, data volume","ru":"объём данных","vi":"lượng dữ liệu","fa":"مقدار داده ها","examples":[{"de":"Die Datenmenge wächst jedes Jahr schneller.","en":"The volume of data grows faster every year.","ru":"Объём данных с каждым годом растёт всё быстрее.","vi":"Lượng dữ liệu đang tăng nhanh hơn mỗi năm.","fa":"حجم داده ها هر سال با سرعت بیشتری در حال رشد است."},{"de":"Für so eine große Datenmenge brauchen wir einen stärkeren Computer.","en":"We need a more powerful computer for such a large amount of data.","ru":"Для такого большого объёма данных нам нужен более мощный компьютер.","vi":"Chúng ta cần một máy tính mạnh hơn để xử lý lượng dữ liệu lớn như vậy.","fa":"ما به یک کامپیوتر قدرتمندتر برای مدیریت چنین حجم زیادی از داده ها نیاز داریم."},{"de":"Die Software kann auch riesige Datenmengen verarbeiten.","en":"The software can also process huge amounts of data.","ru":"Программа может обрабатывать и огромные объёмы данных.","vi":"Phần mềm cũng có thể xử lý lượng dữ liệu khổng lồ.","fa":"این نرم افزار همچنین می تواند حجم عظیمی از داده ها را پردازش کند."}]},{"word":"der Datenpunkt","en":"data point","ru":"точка данных","vi":"điểm dữ liệu","fa":"نقطه داده","examples":[{"de":"Jeder Datenpunkt steht für eine Messung.","en":"Each data point represents one measurement.","ru":"Каждая точка данных соответствует одному измерению.","vi":"Mỗi điểm dữ liệu đại diện cho một phép đo.","fa":"هر نقطه داده نشان دهنده یک اندازه گیری است."},{"de":"In der Grafik fehlt ein wichtiger Datenpunkt.","en":"An important data point is missing in the graphic.","ru":"На графике не хватает важной точки данных.","vi":"Một điểm dữ liệu quan trọng bị thiếu trong đồ họa.","fa":"یک نقطه داده مهم در گرافیک گم شده است."},{"de":"Ein einzelner Datenpunkt sagt noch nichts aus.","en":"A single data point says nothing on its own.","ru":"Одна точка данных сама по себе ничего не говорит.","vi":"Một điểm dữ liệu duy nhất không nói lên điều gì.","fa":"یک نقطه داده تنها چیزی نمی گوید."}]},{"word":"der Datenschutz","en":"data protection, data privacy","ru":"защита данных, конфиденциальность данных","vi":"bảo vệ dữ liệu","fa":"حفاظت از داده ها","examples":[{"de":"Datenschutz ist im Internet besonders wichtig.","en":"Data protection is particularly important on the internet.","ru":"Защита данных особенно важна в интернете.","vi":"Bảo vệ dữ liệu đặc biệt quan trọng trên Internet.","fa":"حفاظت از داده ها به ویژه در اینترنت مهم است."},{"de":"Die Firma nimmt den Datenschutz sehr ernst.","en":"The company takes data protection very seriously.","ru":"Компания очень серьёзно относится к защите данных.","vi":"Công ty rất coi trọng việc bảo vệ dữ liệu.","fa":"این شرکت حفاظت از داده ها را بسیار جدی می گیرد."},{"de":"Ohne Datenschutz sind persönliche Informationen gefährdet.","en":"Without data protection personal information is at risk.","ru":"Без защиты данных личная информация под угрозой.","vi":"Nếu không bảo vệ dữ liệu, thông tin cá nhân sẽ gặp rủi ro.","fa":"بدون حفاظت از داده ها، اطلاعات شخصی در خطر است."}]},{"word":"das Datum","en":"date","ru":"дата","vi":"ngày","fa":"تاریخ","examples":[{"de":"Welches Datum haben wir heute?","en":"What's today's date?","ru":"Какое сегодня число?","vi":"Hôm nay là ngày gì?","fa":"امروز چه تاریخی است؟"},{"de":"Bitte geben Sie Ihr Geburtsdatum an.","en":"Please provide your date of birth.","ru":"Пожалуйста, укажите дату рождения.","vi":"Vui lòng nhập ngày sinh của bạn.","fa":"لطفا تاریخ تولد خود را وارد کنید"}]},{"word":"die Dauer","en":"duration, length (of time)","ru":"длительность, продолжительность","vi":"thời gian","fa":"مدت","examples":[{"de":"Die Dauer des Kurses beträgt drei Monate.","en":"The duration of the course is three months.","ru":"Продолжительность курса — три месяца.","vi":"Thời gian của khóa học là ba tháng.","fa":"مدت دوره سه ماه می باشد."},{"de":"Auf die Dauer wird diese Arbeit langweilig.","en":"In the long run this work gets boring.","ru":"В долгосрочной перспективе эта работа становится скучной.","vi":"Về lâu dài công việc này trở nên nhàm chán.","fa":"در دراز مدت این کار خسته کننده می شود."},{"de":"Die Dauer der Reise hängt vom Wetter ab.","en":"The length of the journey depends on the weather.","ru":"Длительность поездки зависит от погоды.","vi":"Thời gian của chuyến đi phụ thuộc vào thời tiết.","fa":"مدت زمان سفر به آب و هوا بستگی دارد."}]},{"word":"dauern","en":"to last; to take (time)","ru":"длиться","vi":"cuối cùng","fa":"آخرین","examples":[{"de":"Der Film dauert etwa zwei Stunden.","en":"The movie lasts about two hours.","ru":"Фильм длится около двух часов.","vi":"Bộ phim kéo dài khoảng hai giờ.","fa":"فیلم حدود دو ساعت طول می کشد."},{"de":"Wie lange dauert die Fahrt nach München?","en":"How long does the trip to Munich take?","ru":"Сколько длится поездка в Мюнхен?","vi":"Cuộc hành trình đến Munich mất bao lâu?","fa":"سفر به مونیخ چقدر طول می کشد؟"}]},{"word":"dauernd","en":"constantly","ru":"постоянно","vi":"liên tục","fa":"دائما","examples":[{"de":"Er beschwert sich dauernd über das Wetter.","en":"He constantly complains about the weather.","ru":"Он постоянно жалуется на погоду.","vi":"Anh ấy liên tục phàn nàn về thời tiết.","fa":"مدام از آب و هوا شاکی است."},{"de":"Mein Handy klingelt dauernd.","en":"My phone keeps ringing constantly.","ru":"Мой телефон постоянно звонит.","vi":"Điện thoại di động của tôi cứ đổ chuông.","fa":"موبایلم مدام زنگ می زند."}]},{"word":"die Daumen drücken","en":"to keep one's fingers crossed (wish luck)","ru":"держать кулачки (желать удачи)","vi":"để giữ ngón tay của một chéo","fa":"برای نگه داشتن انگشتان دست","examples":[{"de":"Morgen ist deine Prüfung — ich drücke dir die Daumen!","en":"Your exam is tomorrow — I'll keep my fingers crossed for you!","ru":"Завтра твой экзамен — держу за тебя кулачки!","vi":"Kỳ thi của bạn diễn ra vào ngày mai - Tôi rất mong chờ bạn!","fa":"امتحان شما فردا است - من برای شما انگشتان دستم را نگه می دارم!"}]},{"word":"dazugehören","en":"to belong (to it), to be part of it","ru":"относиться к чему-либо, быть частью чего-либо","vi":"thuộc về nó","fa":"متعلق به آن است","examples":[{"de":"Zu einem guten Frühstück gehört für mich Kaffee dazu.","en":"For me, coffee is part of a good breakfast.","ru":"Для меня кофе — неотъемлемая часть хорошего завтрака.","vi":"Đối với tôi, một bữa sáng ngon bao gồm cà phê.","fa":"برای من یک صبحانه خوب شامل قهوه است."},{"de":"Sie möchte einfach dazugehören und Freunde finden.","en":"She just wants to belong and to make friends.","ru":"Она просто хочет быть своей и завести друзей.","vi":"Cô ấy chỉ muốn thuộc về và kết bạn.","fa":"او فقط می خواهد تعلق داشته باشد و دوستی پیدا کند."},{"de":"Zu diesem Beruf gehört viel Geduld dazu.","en":"This job requires a lot of patience.","ru":"Эта профессия требует большого терпения.","vi":"Công việc này đòi hỏi rất nhiều kiên nhẫn.","fa":"این کار به صبر و حوصله زیادی نیاز دارد."}]},{"word":"die Decke","en":"blanket; ceiling","ru":"одеяло; потолок","vi":"trần nhà","fa":"سقف","examples":[{"de":"Nachts liege ich unter einer warmen Decke.","en":"At night I lie under a warm blanket.","ru":"Ночью я лежу под тёплым одеялом.","vi":"Ban đêm tôi nằm trong chăn ấm.","fa":"شب ها زیر یک پتوی گرم دراز می کشم."},{"de":"Die Decke im Wohnzimmer ist sehr hoch.","en":"The ceiling in the living room is very high.","ru":"Потолок в гостиной очень высокий.","vi":"Trần nhà trong phòng khách rất cao.","fa":"سقف اتاق نشیمن بسیار بلند است."}]},{"word":"defekt","en":"faulty, broken, defective","ru":"неисправный, сломанный, дефектный","vi":"khiếm khuyết","fa":"معیوب","examples":[{"de":"Der Aufzug ist leider defekt.","en":"Unfortunately, the lift is out of order.","ru":"Лифт, к сожалению, не работает.","vi":"Thật không may thang máy bị hỏng.","fa":"متاسفانه آسانسور خراب است"},{"de":"Mein Handy ist defekt und lässt sich nicht einschalten.","en":"My phone is broken and won't turn on.","ru":"Мой телефон сломан и не включается.","vi":"Điện thoại của tôi bị hỏng và không bật được.","fa":"گوشیم خرابه و روشن نمیشه"},{"de":"Wir mussten das defekte Gerät zurückgeben.","en":"We had to return the faulty device.","ru":"Нам пришлось вернуть неисправное устройство.","vi":"Chúng tôi đã phải trả lại thiết bị bị lỗi.","fa":"مجبور شدیم دستگاه معیوب را برگردانیم."}]},{"word":"dehnen","en":"to stretch","ru":"растягивать(ся), тянуть","vi":"căng ra","fa":"کشش","examples":[{"de":"Vor dem Sport solltest du dich gut dehnen.","en":"Before exercising you should stretch well.","ru":"Перед спортом тебе стоит хорошо растянуться.","vi":"Bạn nên giãn cơ thật kỹ trước khi tập luyện.","fa":"قبل از ورزش باید کشش خوبی داشته باشید."},{"de":"Diese Übung dehnt die Muskeln in den Beinen.","en":"This exercise stretches the muscles in the legs.","ru":"Это упражнение растягивает мышцы ног.","vi":"Bài tập này kéo giãn các cơ ở chân của bạn.","fa":"این تمرین باعث کشش عضلات پاها می شود."},{"de":"Wenn du das Gummiband zu stark dehnst, reißt es.","en":"If you stretch the rubber band too hard, it snaps.","ru":"Если слишком сильно растянуть резинку, она порвётся.","vi":"Nếu bạn kéo căng dây thun quá nhiều, nó sẽ bị đứt.","fa":"اگر کش را زیاد بکشید، می شکند."}]},{"word":"die Dehnung","en":"stretch, stretching","ru":"растяжка, растягивание","vi":"sự kéo dài","fa":"کشش","examples":[{"de":"Diese Dehnung tut den Beinen gut.","en":"This stretch is good for the legs.","ru":"Эта растяжка полезна для ног.","vi":"Động tác kéo dãn này rất tốt cho đôi chân.","fa":"این کشش برای پاها مفید است."},{"de":"Halte die Dehnung, ohne dabei den Atem anzuhalten.","en":"Hold the stretch without holding your breath.","ru":"Удерживай растяжку, не задерживая при этом дыхание.","vi":"Giữ căng mà không nín thở.","fa":"کشش را بدون حبس نفس نگه دارید."},{"de":"Eine sanfte Dehnung am Morgen weckt den Körper.","en":"A gentle stretch in the morning wakes up the body.","ru":"Мягкая растяжка по утрам пробуждает тело.","vi":"Một động tác giãn cơ nhẹ nhàng vào buổi sáng sẽ đánh thức cơ thể.","fa":"کشش ملایم در صبح بدن را بیدار می کند."}]},{"word":"dekorieren","en":"to decorate","ru":"украшать","vi":"trang trí","fa":"تزئین کنید","examples":[{"de":"Wir dekorieren das Zimmer für die Geburtstagsparty.","en":"We're decorating the room for the birthday party.","ru":"Мы украшаем комнату для дня рождения.","vi":"Chúng tôi trang trí phòng cho bữa tiệc sinh nhật.","fa":"ما اتاق را برای جشن تولد تزئین می کنیم."},{"de":"Zu Weihnachten dekorieren viele Menschen ihre Häuser.","en":"At Christmas many people decorate their houses.","ru":"На Рождество многие люди украшают свои дома.","vi":"Nhiều người trang trí nhà cửa vào dịp Giáng sinh.","fa":"بسیاری از مردم خانه های خود را در کریسمس تزئین می کنند."}]},{"word":"die Delle","en":"dent","ru":"вмятина","vi":"vết lõm","fa":"فرورفتگی","examples":[{"de":"Mein Auto hat eine Delle an der Tür.","en":"My car has a dent in the door.","ru":"На двери моей машины вмятина.","vi":"Xe của tôi có một vết móp ở cửa.","fa":"ماشین من روی درش فرورفتگی دارد."},{"de":"Wer hat diese Delle in das Blech gemacht?","en":"Who made this dent in the metal?","ru":"Кто сделал эту вмятину на металле?","vi":"Ai đã tạo ra vết lõm này trên tấm kim loại?","fa":"چه کسی این فرورفتگی را در ورق فلز ایجاد کرده است؟"},{"de":"Die Delle lässt sich leicht reparieren.","en":"The dent can be repaired easily.","ru":"Вмятину легко починить.","vi":"Vết lõm có thể dễ dàng sửa chữa.","fa":"فرورفتگی به راحتی قابل ترمیم است."}]},{"word":"demnach","en":"accordingly; according to this","ru":"согласно этому; таким образом","vi":"tương ứng","fa":"بر این اساس","examples":[{"de":"Laut Plan sind wir demnach schon fast fertig.","en":"According to the plan, we are therefore almost done.","ru":"Согласно плану, мы таким образом почти закончили.","vi":"Theo kế hoạch, chúng tôi gần như đã hoàn thành.","fa":"طبق برنامه تقریباً کارمان تمام شده است."},{"de":"Die Zahlen sind gestiegen; demnach war die Werbung erfolgreich.","en":"The figures have risen; accordingly, the advertising was successful.","ru":"Цифры выросли; следовательно, реклама была успешной.","vi":"Các con số đã tăng lên; do đó quảng cáo đã thành công.","fa":"اعداد افزایش یافته است. بنابراین تبلیغات موفقیت آمیز بود."}]},{"word":"die Demokratie","en":"democracy","ru":"демократия","vi":"nền dân chủ","fa":"دموکراسی","examples":[{"de":"In einer Demokratie wählt das Volk seine Vertreter selbst.","en":"In a democracy the people elect their own representatives.","ru":"В демократии народ сам выбирает своих представителей.","vi":"Trong một nền dân chủ, người dân chọn người đại diện cho mình.","fa":"در یک دموکراسی، مردم نمایندگان خود را انتخاب می کنند."},{"de":"Die Meinungsfreiheit ist eine wichtige Säule jeder Demokratie.","en":"Freedom of speech is an important pillar of any democracy.","ru":"Свобода слова — важная опора любой демократии.","vi":"Tự do ngôn luận là một trụ cột quan trọng của mọi nền dân chủ.","fa":"آزادی بیان رکن مهم هر دموکراسی است."},{"de":"Nach dem Krieg entwickelte sich das Land langsam zu einer stabilen Demokratie.","en":"After the war the country slowly developed into a stable democracy.","ru":"После войны страна постепенно превратилась в стабильную демократию.","vi":"Sau chiến tranh, đất nước dần dần phát triển thành một nền dân chủ ổn định.","fa":"پس از جنگ، کشور به آرامی به یک دموکراسی پایدار تبدیل شد."}]},{"word":"den","en":"the (masculine accusative); whom, that","ru":"этот (мужской род, винительный падеж); которого, того","vi":"cái","fa":"را","examples":[{"de":"Ich kenne den Mann dort drüben.","en":"I know the man over there.","ru":"Я знаю того мужчину вон там.","vi":"Tôi biết người đàn ông đằng kia.","fa":"من آن مرد را می شناسم."},{"de":"Den Film habe ich schon gesehen.","en":"I've already seen that film.","ru":"Этот фильм я уже видел.","vi":"Tôi đã xem bộ phim rồi.","fa":"من قبلا فیلم را دیده بودم."},{"de":"Der Kollege, den ich meine, ist heute krank.","en":"The colleague I mean is off sick today.","ru":"Коллега, которого я имею в виду, сегодня болеет.","vi":"Người đồng nghiệp mà tôi đang nói đến hôm nay bị ốm.","fa":"همکار مورد نظر من امروز مریض است."}]},{"word":"den Faden verlieren","en":"to lose one's train of thought","ru":"потерять нить (мысли)","vi":"mất đi dòng suy nghĩ của mình","fa":"از دست دادن رشته فکر","examples":[{"de":"Mitten im Vortrag habe ich den Faden verloren.","en":"In the middle of the talk I lost my train of thought.","ru":"Посреди доклада я потерял нить.","vi":"Tôi bị mất chủ đề ở giữa bài giảng.","fa":"وسط سخنرانی تاپیک را گم کردم."}]},{"word":"den Kopf in den Sand stecken","en":"to bury one's head in the sand (avoid a problem)","ru":"прятать голову в песок (избегать проблемы)","vi":"vùi đầu vào cát","fa":"سر در شن فرو کردن","examples":[{"de":"Steck nicht den Kopf in den Sand, wir müssen das lösen.","en":"Don't bury your head in the sand, we have to solve this.","ru":"Не прячь голову в песок, нам нужно это решить.","vi":"Đừng vùi đầu vào cát, chúng ta phải giải quyết chuyện này.","fa":"سرت را در شن فرو نکن، ما باید این را حل کنیم."}]},{"word":"den Nagel auf den Kopf treffen","en":"to hit the nail on the head","ru":"попасть в точку","vi":"đánh cái đinh vào đầu","fa":"ضربه زدن به میخ بر سر","examples":[{"de":"Mit deiner Antwort hast du den Nagel auf den Kopf getroffen.","en":"With your answer you hit the nail on the head.","ru":"Своим ответом ты попал в точку.","vi":"Bạn đã đánh trúng đầu câu trả lời của mình.","fa":"با جوابت به میخ میکوبی."}]},{"word":"denken","en":"to think","ru":"думать","vi":"nghĩ","fa":"فکر کن","examples":[{"de":"Ich denke oft an meine Kindheit.","en":"I often think about my childhood.","ru":"Я часто думаю о своём детстве.","vi":"Tôi thường nghĩ về tuổi thơ của mình.","fa":"اغلب به دوران کودکی ام فکر می کنم."},{"de":"Was denkst du über diesen Plan?","en":"What do you think about this plan?","ru":"Что ты думаешь об этом плане?","vi":"Bạn nghĩ gì về kế hoạch này?","fa":"نظر شما در مورد این طرح چیست؟"}]},{"word":"das Denkmal","en":"monument","ru":"памятник","vi":"tượng đài","fa":"بنای یادبود","examples":[{"de":"In der Stadtmitte steht ein Denkmal für den berühmten Dichter.","en":"In the city center there's a monument for the famous poet.","ru":"В центре города стоит памятник знаменитому поэту.","vi":"Có một tượng đài cho nhà thơ nổi tiếng ở trung tâm thành phố.","fa":"بنای یادبود شاعر معروف در مرکز شهر وجود دارد."},{"de":"Touristen fotografieren gern das Denkmal.","en":"Tourists like to photograph the monument.","ru":"Туристы любят фотографировать памятник.","vi":"Khách du lịch thích chụp ảnh di tích.","fa":"گردشگران دوست دارند از این بنای تاریخی عکس بگیرند."}]},{"word":"denn","en":"because; for","ru":"так как, ведь","vi":"bởi vì","fa":"چون","examples":[{"de":"Ich kann heute nicht kommen, denn ich bin krank.","en":"I can't come today because I'm sick.","ru":"Я не могу прийти сегодня, так как я болею.","vi":"Hôm nay tôi không thể đến vì tôi bị ốm.","fa":"امروز نمیتونم بیام چون مریضم"},{"de":"Beeil dich, denn der Zug fährt gleich ab.","en":"Hurry up, because the train is about to leave.","ru":"Поспеши, ведь поезд вот-вот отправится.","vi":"Hãy nhanh lên vì tàu sắp khởi hành.","fa":"عجله کنید زیرا قطار در شرف حرکت است."}]},{"word":"dennoch","en":"nevertheless; nonetheless","ru":"тем не менее; всё же","vi":"tuy nhiên","fa":"با این وجود","examples":[{"de":"Es regnete stark; dennoch gingen wir spazieren.","en":"It was raining heavily; nevertheless we went for a walk.","ru":"Шёл сильный дождь; тем не менее мы пошли гулять.","vi":"Trời đang mưa rất to; tuy nhiên chúng tôi đã đi dạo.","fa":"باران شدیدی می بارید؛ با این حال رفتیم پیاده روی"},{"de":"Die Aufgabe war schwer, dennoch hat sie es geschafft.","en":"The task was hard, but she managed it nonetheless.","ru":"Задание было трудным, и всё же она справилась.","vi":"Nhiệm vụ khó khăn nhưng cô đã làm được.","fa":"کار سخت بود، اما او آن را انجام داد."}]},{"word":"der","en":"the (masculine); who, that, which","ru":"этот (мужской род); который, тот","vi":"cái","fa":"را","examples":[{"de":"Der Hund schläft auf dem Sofa.","en":"The dog is sleeping on the sofa.","ru":"Собака спит на диване.","vi":"Con chó ngủ trên ghế sofa.","fa":"سگ روی مبل می خوابد."},{"de":"Der Mann, der dort steht, ist mein Lehrer.","en":"The man who is standing there is my teacher.","ru":"Мужчина, который там стоит, — мой учитель.","vi":"Người đàn ông đang đứng đó là thầy của tôi.","fa":"مردی که آنجا ایستاده معلم من است."},{"de":"Der Zug fährt um acht Uhr ab.","en":"The train leaves at eight o'clock.","ru":"Поезд отправляется в восемь часов.","vi":"Tàu khởi hành lúc tám giờ.","fa":"قطار ساعت هشت حرکت می کند."}]},{"word":"derselbe","en":"the same","ru":"тот же самый","vi":"giống nhau","fa":"همان","examples":[{"de":"Wir wohnen im selben Haus.","en":"We live in the same house.","ru":"Мы живём в том же доме.","vi":"Chúng tôi sống trong cùng một ngôi nhà.","fa":"ما در یک خانه زندگی می کنیم."},{"de":"Er trägt jeden Tag denselben Pullover.","en":"He wears the same sweater every day.","ru":"Он каждый день носит один и тот же свитер.","vi":"Anh ấy mặc cùng một chiếc áo len mỗi ngày.","fa":"او هر روز همان ژاکت را می پوشد."}]},{"word":"deshalb","en":"therefore; that's why","ru":"поэтому","vi":"do đó","fa":"بنابراین","examples":[{"de":"Es war kalt, deshalb zog ich eine Jacke an.","en":"It was cold, that's why I put on a jacket.","ru":"Было холодно, поэтому я надел куртку.","vi":"Trời lạnh nên tôi mặc áo khoác vào.","fa":"هوا سرد بود، کت پوشیدم."},{"de":"Sie hat viel gelernt, deshalb hat sie die Prüfung bestanden.","en":"She studied a lot, that's why she passed the exam.","ru":"Она много училась, поэтому сдала экзамен.","vi":"Cô ấy đã học rất nhiều, đó là lý do tại sao cô ấy đã vượt qua kỳ thi.","fa":"او خیلی درس خواند، به همین دلیل در امتحان قبول شد."}]},{"word":"das Dessert","en":"dessert","ru":"десерт","vi":"món tráng miệng","fa":"دسر","examples":[{"de":"Zum Dessert gibt es heute Schokoladenkuchen.","en":"For dessert there's chocolate cake today.","ru":"На десерт сегодня будет шоколадный торт.","vi":"Món tráng miệng hôm nay chúng tôi có bánh sô-cô-la.","fa":"برای دسر امروز کیک شکلاتی داریم."},{"de":"Möchten Sie ein Dessert bestellen?","en":"Would you like to order a dessert?","ru":"Хотите заказать десерт?","vi":"Bạn có muốn gọi món tráng miệng không?","fa":"آیا می خواهید دسر سفارش دهید؟"}]},{"word":"desto","en":"the (second part of je…desto…, marking the proportional result)","ru":"тем (вторая часть je…desto…, вводит соразмерный результат)","vi":"càng nhiều","fa":"بیشتر","examples":[{"de":"Je mehr ich übe, desto besser werde ich.","en":"The more I practise, the better I become.","ru":"Чем больше я тренируюсь, тем лучше становлюсь.","vi":"Càng luyện tập nhiều thì tôi càng tiến bộ hơn.","fa":"هر چه بیشتر تمرین کنم بهتر می شوم."},{"de":"Je mehr ich darüber nachdenke, desto unsicherer werde ich.","en":"The more I think about it, the more uncertain I become.","ru":"Чем больше я об этом думаю, тем больше сомневаюсь.","vi":"Càng nghĩ về nó, tôi càng trở nên không chắc chắn.","fa":"هر چه بیشتر به آن فکر می کنم، مطمئن تر می شوم."},{"de":"Je schneller du sprichst, desto schwerer verstehe ich dich.","en":"The faster you speak, the harder it is for me to understand you.","ru":"Чем быстрее ты говоришь, тем труднее мне тебя понимать.","vi":"Bạn nói càng nhanh thì tôi càng khó hiểu bạn.","fa":"هر چه سریعتر صحبت کنید، درک شما برای من سخت تر است."}]},{"word":"deswegen","en":"therefore, that's why","ru":"поэтому","vi":"đó là lý do tại sao","fa":"به همین دلیل است","examples":[{"de":"Es regnet stark, deswegen bleibe ich heute zu Hause.","en":"It's raining heavily, that's why I'm staying home today.","ru":"Идёт сильный дождь, поэтому я сегодня останусь дома.","vi":"Trời mưa to quá nên hôm nay tôi ở nhà.","fa":"باران شدیدی می بارد، بنابراین من امروز در خانه می مانم."},{"de":"Er hat keine Zeit, deswegen kann er nicht kommen.","en":"He has no time, therefore he can't come.","ru":"У него нет времени, поэтому он не может прийти.","vi":"Anh ấy không có thời gian nên không thể đến được.","fa":"او وقت ندارد، پس نمی تواند بیاید."}]},{"word":"das Detail","en":"detail","ru":"деталь, подробность","vi":"chi tiết","fa":"جزئیات","examples":[{"de":"Er erklärte uns alle Details des Projekts.","en":"He explained all the details of the project to us.","ru":"Он объяснил нам все детали проекта.","vi":"Anh ấy đã giải thích tất cả các chi tiết của dự án cho chúng tôi.","fa":"او تمام جزئیات پروژه را برای ما توضیح داد."},{"de":"Ich möchte die Details später besprechen.","en":"I'd like to discuss the details later.","ru":"Я хотел бы обсудить подробности позже.","vi":"Tôi muốn thảo luận chi tiết sau.","fa":"می خواهم بعداً در مورد جزئیات صحبت کنم."}]},{"word":"deutlich","en":"clear, distinct","ru":"чёткий, ясный","vi":"rõ ràng","fa":"به وضوح","examples":[{"de":"Bitte sprich deutlicher, ich verstehe dich nicht.","en":"Please speak more clearly, I can't understand you.","ru":"Пожалуйста, говори яснее, я тебя не понимаю.","vi":"Bạn nói rõ hơn đi, mình chưa hiểu.","fa":"لطفا واضح تر صحبت کنید، من شما را درک نمی کنم."},{"de":"Die Verbesserung ist deutlich zu erkennen.","en":"The improvement is clearly recognizable.","ru":"Улучшение отчётливо заметно.","vi":"Sự cải thiện có thể nhìn thấy rõ ràng.","fa":"بهبود به وضوح قابل مشاهده است."}]},{"word":"das Deutschzerti","en":"German certificate (colloquial for Deutschzertifikat)","ru":"сертификат по немецкому (разг. от Deutschzertifikat)","vi":"chứng chỉ tiếng Đức","fa":"گواهی آلمانی","examples":[{"de":"Hast du dein Deutschzerti schon bekommen?","en":"Have you already got your German certificate?","ru":"У тебя уже есть сертификат по немецкому?","vi":"Bạn đã nhận được chứng chỉ tiếng Đức chưa?","fa":"آیا قبلاً مدرک آلمانی خود را دریافت کرده اید؟"},{"de":"Für das Studium brauche ich ein Deutschzerti auf B1-Niveau.","en":"For my studies I need a German certificate at B1 level.","ru":"Для учёбы мне нужен сертификат по немецкому уровня B1.","vi":"Đối với việc học của tôi, tôi cần có chứng chỉ tiếng Đức ở cấp độ B1.","fa":"برای تحصیل به مدرک آلمانی در سطح B1 نیاز دارم."},{"de":"Das Deutschzerti ist mehrere Jahre gültig.","en":"The German certificate is valid for several years.","ru":"Сертификат по немецкому действителен несколько лет.","vi":"Chứng chỉ tiếng Đức có giá trị trong vài năm.","fa":"گواهی آلمانی برای چندین سال اعتبار دارد."}]},{"word":"der Dialekt","en":"dialect","ru":"диалект","vi":"phương ngữ","fa":"گویش","examples":[{"de":"In Bayern spricht man einen besonderen Dialekt.","en":"In Bavaria, people speak a special dialect.","ru":"В Баварии говорят на особом диалекте.","vi":"Ở Bavaria họ nói một phương ngữ đặc biệt.","fa":"در باواریا به گویش خاصی صحبت می کنند."},{"de":"Ich verstehe den Schweizer Dialekt nur schwer.","en":"I find it hard to understand the Swiss dialect.","ru":"Мне трудно понимать швейцарский диалект.","vi":"Tôi gặp khó khăn trong việc hiểu phương ngữ Thụy Sĩ.","fa":"من در درک لهجه سوئیسی مشکل دارم."}]},{"word":"der Dialog","en":"dialogue","ru":"диалог","vi":"cuộc đối thoại","fa":"دیالوگ","examples":[{"de":"Die Politiker suchen einen Dialog mit den Bürgern.","en":"The politicians are seeking a dialogue with the citizens.","ru":"Политики ищут диалог с гражданами.","vi":"Các chính trị gia tìm kiếm đối thoại với người dân.","fa":"سیاستمداران به دنبال گفتگو با شهروندان هستند."},{"de":"Im Deutschunterricht üben wir kurze Dialoge.","en":"In German class we practice short dialogues.","ru":"На уроке немецкого мы практикуем короткие диалоги.","vi":"Trong lớp học tiếng Đức, chúng tôi thực hành các đoạn hội thoại ngắn.","fa":"در کلاس آلمانی دیالوگ های کوتاه را تمرین می کنیم."}]},{"word":"die Diät","en":"diet","ru":"диета","vi":"chế độ ăn kiêng","fa":"رژیم غذایی","examples":[{"de":"Meine Mutter macht seit einem Monat eine Diät.","en":"My mother has been on a diet for a month.","ru":"Моя мама уже месяц сидит на диете.","vi":"Mẹ tôi đã ăn kiêng được một tháng.","fa":"مادرم یک ماه است که رژیم گرفته است."},{"de":"Der Arzt hat ihm eine strenge Diät verordnet.","en":"The doctor prescribed him a strict diet.","ru":"Врач прописал ему строгую диету.","vi":"Bác sĩ kê cho anh một chế độ ăn kiêng nghiêm ngặt.","fa":"دکتر برای او رژیم غذایی سختی تجویز کرد."}]},{"word":"dicht","en":"dense; sealed, tight","ru":"плотный, герметичный","vi":"dày đặc; kín","fa":"متراکم؛ محکم","examples":[{"de":"Der Wald hier ist sehr dicht.","en":"The forest here is very dense.","ru":"Лес здесь очень густой.","vi":"Rừng ở đây rất rậm rạp.","fa":"جنگل اینجا بسیار متراکم است."},{"de":"Das Fenster ist nicht dicht, es zieht.","en":"The window isn't sealed properly, there's a draft.","ru":"Окно неплотно закрыто, дует.","vi":"Cửa sổ không kín, đang có gió lùa.","fa":"پنجره تنگ نیست، در حال پیش نویس است."}]},{"word":"die Dichte","en":"density","ru":"плотность","vi":"mật độ","fa":"تراکم","examples":[{"de":"Die Dichte von Wasser beträgt etwa ein Gramm pro Kubikzentimeter.","en":"The density of water is about one gram per cubic centimetre.","ru":"Плотность воды составляет около одного грамма на кубический сантиметр.","vi":"Mật độ của nước là khoảng một gram trên mỗi centimet khối.","fa":"چگالی آب حدود یک گرم در سانتی متر مکعب است."},{"de":"Öl hat eine geringere Dichte als Wasser, deshalb schwimmt es oben.","en":"Oil has a lower density than water, so it floats on top.","ru":"У масла плотность меньше, чем у воды, поэтому оно плавает сверху.","vi":"Dầu nhẹ hơn nước nên nổi lên trên.","fa":"چگالی روغن کمتر از آب است، بنابراین روی آن شناور است."},{"de":"Die Dichte ist Masse geteilt durch Volumen.","en":"Density is mass divided by volume.","ru":"Плотность — это масса, делённая на объём.","vi":"Mật độ là khối lượng chia cho thể tích.","fa":"چگالی جرم تقسیم بر حجم است."}]},{"word":"dick","en":"thick; fat","ru":"толстый","vi":"dày","fa":"ضخیم","examples":[{"de":"Das Buch ist sehr dick, über 800 Seiten.","en":"The book is very thick, over 800 pages.","ru":"Книга очень толстая, более 800 страниц.","vi":"Sách rất dày, hơn 800 trang.","fa":"کتاب بسیار قطور است، بیش از 800 صفحه."},{"de":"Im Winter ziehe ich eine dicke Jacke an.","en":"In winter I wear a thick jacket.","ru":"Зимой я надеваю толстую куртку.","vi":"Vào mùa đông tôi mặc một chiếc áo khoác dày.","fa":"در زمستان یک ژاکت ضخیم می پوشم."}]},{"word":"die","en":"the (feminine/plural); who, that, which","ru":"эта, эти (женский род / множественное число); которая, которые","vi":"cái","fa":"را","examples":[{"de":"Die Frau wartet vor der Tür.","en":"The woman is waiting in front of the door.","ru":"Женщина ждёт перед дверью.","vi":"Người phụ nữ đang đợi ngoài cửa.","fa":"زن بیرون در منتظر است."},{"de":"Die Kinder spielen im Garten.","en":"The children are playing in the garden.","ru":"Дети играют в саду.","vi":"Bọn trẻ đang chơi trong vườn.","fa":"بچه ها در باغ بازی می کنند."},{"de":"Die Frau, die dort sitzt, ist meine Tante.","en":"The woman who is sitting there is my aunt.","ru":"Женщина, которая там сидит, — моя тётя.","vi":"Người phụ nữ ngồi đó là dì của tôi.","fa":"خانمی که آنجا نشسته عمه من است."}]},{"word":"der Dieb","en":"thief","ru":"вор","vi":"tên trộm","fa":"دزد","examples":[{"de":"Der Dieb wurde von der Polizei gefasst.","en":"The thief was caught by the police.","ru":"Вора поймала полиция.","vi":"Tên trộm đã bị cảnh sát bắt.","fa":"دزد توسط پلیس دستگیر شد."},{"de":"Ein Dieb hat mein Fahrrad gestohlen.","en":"A thief stole my bicycle.","ru":"Вор украл мой велосипед.","vi":"Một tên trộm đã lấy trộm chiếc xe đạp của tôi.","fa":"دزد دوچرخه ام را دزدید"}]},{"word":"die/das Glace/Glacé","en":"ice cream","ru":"мороженое","vi":"kem/kem","fa":"بستنی/بستنی","examples":[{"de":"Im Sommer essen wir gerne ein Glace.","en":"In summer we like to eat ice cream.","ru":"Летом мы любим есть мороженое.","vi":"Vào mùa hè chúng tôi thích ăn kem.","fa":"در تابستان دوست داریم بستنی بخوریم."},{"de":"Welche Sorte Glace möchtest du: Schokolade oder Vanille?","en":"Which flavor of ice cream would you like: chocolate or vanilla?","ru":"Какое мороженое ты хочешь: шоколадное или ванильное?","vi":"Bạn muốn loại kem nào: sô cô la hay vani?","fa":"کدام نوع بستنی می خواهید: شکلاتی یا وانیلی؟"}]},{"word":"dienen","en":"to serve","ru":"служить","vi":"phục vụ","fa":"خدمت کنید","examples":[{"de":"Dieser Raum dient als Lager.","en":"This room serves as a storage room.","ru":"Это помещение служит складом.","vi":"Căn phòng này được dùng làm kho chứa đồ.","fa":"این اتاق به عنوان انبار عمل می کند."},{"de":"Er hat lange in der Armee gedient.","en":"He served in the army for a long time.","ru":"Он долго служил в армии.","vi":"Ông đã phục vụ trong quân đội một thời gian dài.","fa":"مدت زیادی در ارتش خدمت کرد."}]},{"word":"der Dienst","en":"service; duty","ru":"служба, дежурство","vi":"dịch vụ","fa":"خدمات","examples":[{"de":"Der Kellner ist heute im Dienst.","en":"The waiter is on duty today.","ru":"Официант сегодня на смене.","vi":"Hôm nay người phục vụ đang trực.","fa":"گارسون امروز در حال انجام وظیفه است."},{"de":"Die Firma bietet einen guten Kundendienst.","en":"The company offers good customer service.","ru":"Компания предлагает хорошее обслуживание клиентов.","vi":"Công ty cung cấp dịch vụ khách hàng tốt.","fa":"این شرکت خدمات خوبی به مشتریان ارائه می دهد."}]},{"word":"die Dienstreise","en":"business trip","ru":"командировка, служебная поездка","vi":"chuyến công tác","fa":"سفر کاری","examples":[{"de":"Mein Chef ist diese Woche auf einer Dienstreise.","en":"My boss is on a business trip this week.","ru":"Мой начальник на этой неделе в командировке.","vi":"Tuần này sếp tôi đang đi công tác.","fa":"رئیس من این هفته در یک سفر کاری است."},{"de":"Die Dienstreise nach München dauert drei Tage.","en":"The business trip to Munich lasts three days.","ru":"Командировка в Мюнхен длится три дня.","vi":"Chuyến công tác tới Munich kéo dài ba ngày.","fa":"سفر کاری به مونیخ سه روز طول می کشد."},{"de":"Auf der Dienstreise habe ich viele Kollegen getroffen.","en":"On the business trip I met many colleagues.","ru":"В командировке я встретил много коллег.","vi":"Tôi đã gặp nhiều đồng nghiệp trong chuyến công tác.","fa":"در سفر کاری با همکاران زیادی آشنا شدم."}]},{"word":"dies","en":"this, these (demonstrative)","ru":"это, сие (указательное)","vi":"cái này","fa":"این","examples":[{"de":"Dies ist mein letztes Wort.","en":"This is my final word.","ru":"Это моё последнее слово.","vi":"Đây là lời cuối cùng của tôi.","fa":"این حرف آخر من است."},{"de":"Dies alles gehört dir.","en":"All of this belongs to you.","ru":"Всё это принадлежит тебе.","vi":"Đây là tất cả của bạn.","fa":"این همه مال توست"},{"de":"Trotz alledem mochte er dies nicht sagen.","en":"In spite of everything, he didn't want to say this.","ru":"Несмотря ни на что, он не хотел этого говорить.","vi":"Bất chấp tất cả những điều này, anh không muốn nói điều này.","fa":"با همه اینها نمی خواست این حرف را بزند."}]},{"word":"dies-","en":"this (stem of dieser/diese/dieses)","ru":"этот, эта, это","vi":"cái này-","fa":"این -","examples":[{"de":"Dieser Mann ist mein Nachbar.","en":"This man is my neighbor.","ru":"Этот мужчина — мой сосед.","vi":"Người đàn ông này là hàng xóm của tôi.","fa":"این مرد همسایه من است."},{"de":"Diese Woche habe ich viel zu tun.","en":"This week I have a lot to do.","ru":"На этой неделе у меня много дел.","vi":"Tôi có rất nhiều việc phải làm trong tuần này.","fa":"این هفته کارهای زیادی برای انجام دادن دارم."}]},{"word":"diese","en":"this/these (feminine sg. or plural)","ru":"эта, эти (женский род ед. ч. или мн. ч.)","vi":"những cái này","fa":"اینها","examples":[{"de":"Diese Frau kenne ich aus dem Kurs.","en":"I know this woman from the course.","ru":"Я знаю эту женщину по курсу.","vi":"Tôi biết người phụ nữ này từ khóa học.","fa":"من این زن را از دوره می شناسم."},{"de":"Diese Schuhe sind mir zu klein.","en":"These shoes are too small for me.","ru":"Эти туфли мне малы.","vi":"Đôi giày này quá nhỏ đối với tôi.","fa":"این کفش ها برای من خیلی کوچک هستند."},{"de":"Diese Woche habe ich viel zu tun.","en":"This week I have a lot to do.","ru":"На этой неделе у меня много дел.","vi":"Tôi có rất nhiều việc phải làm trong tuần này.","fa":"این هفته کارهای زیادی برای انجام دادن دارم."}]},{"word":"dieselbe","en":"the same (feminine)","ru":"та же самая (женский род)","vi":"giống nhau","fa":"همان","examples":[{"de":"Wir haben dieselbe Lehrerin wie letztes Jahr.","en":"We have the same teacher as last year.","ru":"У нас та же учительница, что и в прошлом году.","vi":"Chúng ta có cùng một giáo viên như năm ngoái.","fa":"ما همان معلم پارسال را داریم."},{"de":"Sie trägt heute dieselbe Jacke wie gestern.","en":"She's wearing the same jacket today as yesterday.","ru":"Сегодня она в той же куртке, что и вчера.","vi":"Hôm nay cô ấy mặc chiếc áo khoác giống như ngày hôm qua.","fa":"او امروز همان کاپشن دیروز را پوشیده است."},{"de":"Das ist genau dieselbe Frage wie vorhin.","en":"That's exactly the same question as before.","ru":"Это в точности тот же вопрос, что и раньше.","vi":"Đây chính xác là câu hỏi tương tự như trước đây.","fa":"این دقیقاً همان سؤال قبلی است."}]},{"word":"dieser","en":"this (masculine); this one","ru":"этот (мужской род); этот вот","vi":"cái này","fa":"این یکی","examples":[{"de":"Dieser Mann hat mir geholfen.","en":"This man helped me.","ru":"Этот мужчина мне помог.","vi":"Người đàn ông này đã giúp tôi.","fa":"این مرد به من کمک کرد."},{"de":"An diesem Tag hat es nicht geregnet.","en":"It didn't rain on this day.","ru":"В этот день не было дождя.","vi":"Hôm đó trời không mưa.","fa":"آن روز باران نبارید."},{"de":"Dieser Wein schmeckt ausgezeichnet.","en":"This wine tastes excellent.","ru":"Это вино превосходно на вкус.","vi":"Rượu này có hương vị tuyệt vời.","fa":"این شراب طعم عالی دارد."}]},{"word":"dieses","en":"this (neuter); this one","ru":"это, этот (средний род); этот вот","vi":"cái này","fa":"این یکی","examples":[{"de":"Dieses Buch habe ich schon gelesen.","en":"I've already read this book.","ru":"Эту книгу я уже прочитал.","vi":"Tôi đã đọc cuốn sách này rồi.","fa":"من قبلا این کتاب را خوانده ام."},{"de":"Dieses Jahr fahren wir nach Italien.","en":"This year we're going to Italy.","ru":"В этом году мы едем в Италию.","vi":"Năm nay chúng tôi sẽ đến Ý.","fa":"امسال به ایتالیا می رویم."},{"de":"Wem gehört dieses Auto?","en":"Whose car is this?","ru":"Чья это машина?","vi":"Ai sở hữu chiếc xe này?","fa":"این ماشین متعلق به کیست؟"}]},{"word":"diesmal","en":"this time","ru":"на этот раз","vi":"lần này","fa":"این بار","examples":[{"de":"Diesmal hast du wirklich Glück gehabt.","en":"This time you were really lucky.","ru":"На этот раз тебе правда повезло.","vi":"Lần này bạn thực sự may mắn.","fa":"این بار واقعا خوش شانس بودی"},{"de":"Diesmal möchte ich gewinnen.","en":"This time I want to win.","ru":"На этот раз я хочу выиграть.","vi":"Lần này tôi muốn giành chiến thắng.","fa":"این بار می خواهم برنده شوم."},{"de":"Lass uns diesmal früher losfahren.","en":"Let's set off earlier this time.","ru":"Давай на этот раз выедем пораньше.","vi":"Lần này chúng ta hãy rời đi sớm hơn nhé.","fa":"این بار زودتر برویم"}]},{"word":"die Differenz","en":"difference (result of subtraction)","ru":"разность (результат вычитания)","vi":"sự khác biệt","fa":"تفاوت","examples":[{"de":"Die Differenz von zehn und drei ist sieben.","en":"The difference between ten and three is seven.","ru":"Разность десяти и трёх равна семи.","vi":"Sự khác biệt giữa mười và ba là bảy.","fa":"تفاوت ده تا سه هفت است."},{"de":"Bei der Subtraktion nennt man das Ergebnis Differenz.","en":"In subtraction the result is called the difference.","ru":"При вычитании результат называют разностью.","vi":"Khi trừ đi, kết quả được gọi là hiệu.","fa":"هنگام تفریق به نتیجه تفاضل می گویند."},{"de":"Die Differenz zwischen den beiden Werten ist sehr klein.","en":"The difference between the two values is very small.","ru":"Разность между двумя значениями очень мала.","vi":"Sự khác biệt giữa hai giá trị là rất nhỏ.","fa":"تفاوت بین این دو مقدار بسیار کم است."}]},{"word":"digital","en":"digital","ru":"цифровой","vi":"kỹ thuật số","fa":"دیجیتال","examples":[{"de":"Wir speichern alle Dokumente digital.","en":"We save all documents digitally.","ru":"Мы храним все документы в цифровом виде.","vi":"Chúng tôi lưu trữ tất cả các tài liệu kỹ thuật số.","fa":"ما تمام اسناد را به صورت دیجیتال ذخیره می کنیم."},{"de":"Meine Oma benutzt keine digitalen Geräte.","en":"My grandma doesn't use digital devices.","ru":"Моя бабушка не пользуется цифровыми устройствами.","vi":"Bà tôi không sử dụng thiết bị kỹ thuật số.","fa":"مادربزرگ من از دستگاه های دیجیتال استفاده نمی کند."}]},{"word":"die Diktatur","en":"dictatorship","ru":"диктатура","vi":"chế độ độc tài","fa":"the dictatorship","examples":[{"de":"Während der Diktatur gab es keine freien Wahlen.","en":"During the dictatorship there were no free elections.","ru":"Во время диктатуры не было свободных выборов.","vi":"Không có cuộc bầu cử tự do trong thời kỳ độc tài.","fa":"در دوران دیکتاتوری انتخابات آزاد برگزار نشد."},{"de":"Die Diktatur unterdrückte jede Form von Widerstand.","en":"The dictatorship suppressed every form of resistance.","ru":"Диктатура подавляла любую форму сопротивления.","vi":"Chế độ độc tài đàn áp mọi hình thức phản kháng.","fa":"دیکتاتوری همه اشکال مقاومت را سرکوب کرد."},{"de":"Nach dem Ende der Diktatur entstand eine Demokratie.","en":"After the end of the dictatorship a democracy emerged.","ru":"После окончания диктатуры возникла демократия.","vi":"Sau khi chế độ độc tài kết thúc, một nền dân chủ đã xuất hiện.","fa":"پس از پایان دیکتاتوری، دموکراسی به وجود آمد."}]},{"word":"das Ding","en":"thing","ru":"вещь","vi":"điều đó","fa":"چیز","examples":[{"de":"Räum bitte deine Dinge vom Tisch weg.","en":"Please clear your things off the table.","ru":"Убери, пожалуйста, свои вещи со стола.","vi":"Vui lòng dọn đồ đạc của bạn khỏi bàn.","fa":"لطفا وسایل خود را از روی میز پاک کنید."},{"de":"Das ist ein wichtiges Ding für mich.","en":"That's an important thing for me.","ru":"Это важная для меня вещь.","vi":"Đây là một điều quan trọng đối với tôi.","fa":"این برای من یک چیز مهم است."}]},{"word":"das Diplom","en":"diploma","ru":"диплом","vi":"bằng tốt nghiệp","fa":"دیپلم","examples":[{"de":"Sie hat ihr Diplom mit Auszeichnung bekommen.","en":"She received her diploma with honors.","ru":"Она получила диплом с отличием.","vi":"Cô đã nhận được bằng tốt nghiệp danh dự của mình.","fa":"او دیپلم خود را با ممتاز دریافت کرد."},{"de":"Nach dem Studium erhält man ein Diplom.","en":"After studying you receive a diploma.","ru":"После учёбы получают диплом.","vi":"Sau khi học bạn nhận được bằng tốt nghiệp.","fa":"پس از تحصیل دیپلم می گیرید."}]},{"word":"direkt","en":"direct, directly","ru":"прямой, прямо","vi":"trực tiếp","fa":"مستقیما","examples":[{"de":"Der Zug fährt direkt nach Berlin.","en":"The train goes directly to Berlin.","ru":"Поезд идёт прямо в Берлин.","vi":"Tàu đi thẳng đến Berlin.","fa":"قطار مستقیماً به برلین می رود."},{"de":"Frag ihn doch direkt, was er denkt.","en":"Just ask him directly what he thinks.","ru":"Спроси его прямо, что он думает.","vi":"Hãy hỏi trực tiếp anh ấy xem anh ấy nghĩ gì.","fa":"مستقیماً از او بپرسید که چه فکری می کند."}]},{"word":"der Direktor","en":"director, principal","ru":"директор","vi":"giám đốc","fa":"کارگردان","examples":[{"de":"Der Direktor der Schule begrüßte alle Schüler.","en":"The school principal welcomed all the students.","ru":"Директор школы поприветствовал всех учеников.","vi":"Hiệu trưởng nhà trường chào đón tất cả học sinh.","fa":"مدیر مدرسه به همه دانش آموزان خیر مقدم گفت."},{"de":"Sie spricht morgen mit dem Direktor der Firma.","en":"Tomorrow she is speaking with the company director.","ru":"Завтра она будет говорить с директором фирмы.","vi":"Cô ấy sẽ nói chuyện với giám đốc công ty vào ngày mai.","fa":"او فردا با مدیر شرکت صحبت می کند."}]},{"word":"die Direktorin","en":"director, headmistress (female)","ru":"директор, руководительница (жен.)","vi":"giám đốc","fa":"کارگردان","examples":[{"de":"Die Direktorin begrüßte die neuen Mitarbeiter.","en":"The director welcomed the new employees.","ru":"Директор поприветствовала новых сотрудников.","vi":"Giám đốc chào đón nhân viên mới.","fa":"مدیر از کارکنان جدید استقبال کرد."},{"de":"Unsere Direktorin ist sehr freundlich und gerecht.","en":"Our director is very friendly and fair.","ru":"Наша директор очень приветливая и справедливая.","vi":"Giám đốc của chúng tôi rất thân thiện và công bằng.","fa":"کارگردان ما بسیار مهربان و منصف است."},{"de":"Die Direktorin leitet die Firma seit fünf Jahren.","en":"The director has led the company for five years.","ru":"Директор руководит фирмой уже пять лет.","vi":"Giám đốc đã điều hành công ty được 5 năm.","fa":"این مدیر پنج سال است که این شرکت را اداره می کند."}]},{"word":"die Diskothek","en":"disco, nightclub","ru":"дискотека","vi":"vũ trường","fa":"دیسکوتک","examples":[{"de":"Am Wochenende gehen wir in die Diskothek.","en":"On the weekend we're going to the disco.","ru":"На выходных мы идём на дискотеку.","vi":"Cuối tuần chúng tôi đi vũ trường.","fa":"آخر هفته به دیسکوتک می رویم."},{"de":"Die Diskothek hat erst um 22 Uhr geöffnet.","en":"The disco only opens at 10 p.m.","ru":"Дискотека открывается только в 22:00.","vi":"Sàn nhảy không mở cửa cho đến 10 giờ tối.","fa":"دیسکو تا ساعت 10 شب باز نمی شود."}]},{"word":"die Diskriminierung","en":"discrimination","ru":"дискриминация","vi":"sự phân biệt đối xử","fa":"تبعیض","examples":[{"de":"Diskriminierung wegen der Herkunft ist verboten.","en":"Discrimination because of one's origin is forbidden.","ru":"Дискриминация по происхождению запрещена.","vi":"Phân biệt đối xử dựa trên nguồn gốc đều bị cấm.","fa":"تبعیض بر اساس مبدأ ممنوع است."},{"de":"Viele Menschen kämpfen gegen Diskriminierung.","en":"Many people fight against discrimination.","ru":"Многие люди борются с дискриминацией.","vi":"Nhiều người đấu tranh chống lại sự phân biệt đối xử.","fa":"بسیاری از مردم با تبعیض مبارزه می کنند."},{"de":"Diskriminierung am Arbeitsplatz darf nicht akzeptiert werden.","en":"Discrimination in the workplace must not be accepted.","ru":"Дискриминацию на рабочем месте нельзя терпеть.","vi":"Sự phân biệt đối xử ở nơi làm việc không được chấp nhận.","fa":"تبعیض در محل کار را نباید پذیرفت."}]},{"word":"die Diskussion","en":"discussion","ru":"дискуссия, обсуждение","vi":"cuộc thảo luận","fa":"بحث","examples":[{"de":"Die Diskussion über das Thema dauerte zwei Stunden.","en":"The discussion about the topic lasted two hours.","ru":"Обсуждение темы длилось два часа.","vi":"Cuộc thảo luận về chủ đề này kéo dài hai giờ.","fa":"بحث در مورد این موضوع دو ساعت به طول انجامید."},{"de":"In der Diskussion gab es viele verschiedene Meinungen.","en":"In the discussion there were many different opinions.","ru":"В дискуссии прозвучало много разных мнений.","vi":"Trong cuộc thảo luận có nhiều ý kiến ​​khác nhau.","fa":"در این بحث نظرات مختلفی وجود داشت."},{"de":"Das Thema sorgte für eine heftige Diskussion.","en":"The topic caused a heated discussion.","ru":"Тема вызвала жаркую дискуссию.","vi":"Chủ đề này đã gây ra một cuộc thảo luận sôi nổi.","fa":"موضوع باعث بحث داغ شد."}]},{"word":"diskutieren","en":"to discuss","ru":"обсуждать","vi":"thảo luận","fa":"بحث کنید","examples":[{"de":"Wir diskutieren gerade über das neue Projekt.","en":"We are currently discussing the new project.","ru":"Мы сейчас обсуждаем новый проект.","vi":"Chúng tôi hiện đang thảo luận về dự án mới.","fa":"در حال حاضر در حال بحث در مورد پروژه جدید هستیم."},{"de":"In der Klasse diskutieren die Schüler über Politik.","en":"In class the students discuss politics.","ru":"В классе ученики обсуждают политику.","vi":"Trong lớp, học sinh thảo luận về chính trị.","fa":"در کلاس، دانش آموزان درباره سیاست بحث می کنند."}]},{"word":"die Distanz","en":"distance","ru":"расстояние, дистанция","vi":"khoảng cách","fa":"فاصله","examples":[{"de":"Zwischen den beiden Städten liegt eine große Distanz.","en":"There is a great distance between the two cities.","ru":"Между этими двумя городами большое расстояние.","vi":"Có một khoảng cách lớn giữa hai thành phố.","fa":"بین این دو شهر فاصله زیادی وجود دارد."},{"de":"Er hält immer eine gewisse Distanz zu Fremden.","en":"He always keeps a certain distance from strangers.","ru":"Он всегда держит дистанцию с незнакомыми людьми.","vi":"Anh ấy luôn giữ một khoảng cách nhất định với người lạ.","fa":"او همیشه فاصله خاصی را با غریبه ها حفظ می کند."}]},{"word":"dividieren","en":"to divide","ru":"делить","vi":"chia","fa":"تقسیم کنید","examples":[{"de":"Man kann nicht durch null dividieren.","en":"You cannot divide by zero.","ru":"На ноль делить нельзя.","vi":"Bạn không thể chia cho số 0.","fa":"شما نمی توانید بر صفر تقسیم کنید."},{"de":"Dividiere die Summe durch die Anzahl der Werte.","en":"Divide the sum by the number of values.","ru":"Раздели сумму на количество значений.","vi":"Chia tổng cho số lượng giá trị.","fa":"مجموع را بر تعداد مقادیر تقسیم کنید."},{"de":"Wenn du zwölf durch vier dividierst, erhältst du drei.","en":"If you divide twelve by four, you get three.","ru":"Если разделить двенадцать на четыре, получишь три.","vi":"Nếu bạn chia mười hai cho bốn, bạn sẽ nhận được ba.","fa":"اگر دوازده را بر چهار تقسیم کنید، سه به دست می آید."}]},{"word":"die Division","en":"division","ru":"деление","vi":"sự phân chia","fa":"تقسیم","examples":[{"de":"Die Division durch null ist nicht erlaubt.","en":"Division by zero is not allowed.","ru":"Деление на ноль не разрешено.","vi":"Không được phép chia cho số 0.","fa":"تقسیم بر صفر مجاز نیست."},{"de":"Bei der Division teilt man eine Zahl in gleiche Teile.","en":"In division you split a number into equal parts.","ru":"При делении число разбивают на равные части.","vi":"Phép chia bao gồm việc chia một số thành các phần bằng nhau.","fa":"تقسیم شامل تقسیم یک عدد به قسمت های مساوی است."},{"de":"Die Division von 20 durch 4 ergibt 5.","en":"The division of 20 by 4 gives 5.","ru":"Деление 20 на 4 даёт 5.","vi":"Chia 20 cho 4 được 5.","fa":"از تقسیم 20 بر 4 عدد 5 بدست می آید."}]},{"word":"doch","en":"still, after all; (contradicting a negative) yes it is/does","ru":"всё же, ведь; да нет же (в ответ на отрицание)","vi":"vâng","fa":"بله","examples":[{"de":"Kommst du nicht mit? – Doch, ich komme mit!","en":"Aren't you coming along? – Yes, I am!","ru":"Ты не пойдёшь с нами? — Да нет, пойду!","vi":"Bạn không đi cùng tôi à? - Ừ, tôi đi cùng cậu!","fa":"با من نمیای؟ - بله، من با شما می آیم!"},{"de":"Er ist doch noch ein Kind, sei nicht so streng.","en":"He's still just a child, don't be so strict.","ru":"Он же ещё ребёнок, не будь таким строгим.","vi":"Nó vẫn còn là một đứa trẻ, đừng khắt khe như vậy.","fa":"او هنوز بچه است، اینقدر سخت گیر نباش."}]},{"word":"der Doktor","en":"doctor","ru":"доктор, врач","vi":"bác sĩ","fa":"دکتر","examples":[{"de":"Sie hat in Chemie promoviert und ist jetzt Doktor.","en":"She earned her doctorate in chemistry and is now a doctor.","ru":"Она защитила докторскую по химии и теперь доктор наук.","vi":"Cô đã nhận bằng Tiến sĩ hóa học và hiện là bác sĩ.","fa":"او دکترای خود را در رشته شیمی دریافت کرد و اکنون دکتر است."},{"de":"Ich muss morgen zum Doktor gehen.","en":"I have to go to the doctor tomorrow.","ru":"Мне завтра нужно пойти к врачу.","vi":"Ngày mai tôi phải đi khám bác sĩ.","fa":"فردا باید برم دکتر"}]},{"word":"die Doktorin","en":"doctor (female, academic/medical title)","ru":"врач, доктор (жен., учёное/медицинское звание)","vi":"bác sĩ","fa":"دکتر","examples":[{"de":"Die Doktorin untersuchte den Patienten sorgfältig.","en":"The doctor examined the patient carefully.","ru":"Врач внимательно осмотрела пациента.","vi":"Bác sĩ khám bệnh nhân cẩn thận.","fa":"دکتر بیمار را به دقت معاینه کرد."},{"de":"Meine Doktorin hat mir ein neues Medikament verschrieben.","en":"My doctor prescribed me a new medicine.","ru":"Мой врач выписала мне новое лекарство.","vi":"Bác sĩ kê cho tôi một loại thuốc mới.","fa":"دکترم یه داروی جدید برام تجویز کرد."},{"de":"Frau Müller ist Doktorin der Chemie.","en":"Ms Müller is a doctor of chemistry.","ru":"Госпожа Мюллер — доктор химических наук.","vi":"Bà Müller có bằng tiến sĩ hóa học.","fa":"خانم مولر دکترای شیمی دارد."}]},{"word":"das Dokument","en":"document","ru":"документ","vi":"tài liệu","fa":"سند","examples":[{"de":"Bitte bringen Sie alle wichtigen Dokumente mit.","en":"Please bring all the important documents with you.","ru":"Пожалуйста, принесите все важные документы.","vi":"Vui lòng mang theo tất cả các tài liệu quan trọng với bạn.","fa":"لطفا تمام مدارک مهم را همراه داشته باشید."},{"de":"Ich habe das Dokument als PDF gespeichert.","en":"I saved the document as a PDF.","ru":"Я сохранил документ в формате PDF.","vi":"Tôi đã lưu tài liệu dưới dạng PDF.","fa":"من سند را به صورت PDF ذخیره کردم."}]},{"word":"die Dokumentation","en":"documentation, documentary","ru":"документация; документальный фильм","vi":"tài liệu","fa":"مستندات","examples":[{"de":"Gestern habe ich eine Dokumentation über Tiere gesehen.","en":"Yesterday I watched a documentary about animals.","ru":"Вчера я смотрел документальный фильм о животных.","vi":"Hôm qua tôi đã xem một bộ phim tài liệu về động vật.","fa":"دیروز یک مستند در مورد حیوانات دیدم."},{"de":"Die Dokumentation des Projekts ist sehr ausführlich.","en":"The documentation of the project is very detailed.","ru":"Документация проекта очень подробная.","vi":"Tài liệu của dự án rất chi tiết.","fa":"مستندات پروژه بسیار دقیق است."},{"de":"Ohne gute Dokumentation versteht niemand den Code.","en":"Without good documentation nobody understands the code.","ru":"Без хорошей документации никто не разберётся в коде.","vi":"Không có tài liệu tốt, không ai hiểu được mã.","fa":"بدون مستندات خوب، هیچ کس کد را درک نمی کند."}]},{"word":"donnern","en":"to thunder","ru":"греметь (о громе)","vi":"sấm sét","fa":"رعد و برق","examples":[{"de":"Draußen blitzt und donnert es sehr laut.","en":"Outside there's lightning and it's thundering very loudly.","ru":"На улице сверкает молния и громко гремит гром.","vi":"Bên ngoài có sấm sét và sấm sét rất lớn.","fa":"رعد و برق و رعد و برق بسیار شدید بیرون می آید."},{"de":"Es donnerte die ganze Nacht.","en":"It thundered all night.","ru":"Всю ночь гремел гром.","vi":"Nó sấm sét suốt đêm dài.","fa":"تمام شب رعد و برق می زد."}]},{"word":"doppel-","en":"double- (prefix)","ru":"двойной, двух- (приставка)","vi":"gấp đôi","fa":"دو برابر کردن","examples":[{"de":"Wir haben ein Doppelzimmer im Hotel gebucht.","en":"We booked a double room at the hotel.","ru":"Мы забронировали в отеле двухместный номер.","vi":"Chúng tôi đặt một phòng đôi trong khách sạn.","fa":"ما یک اتاق دو نفره در هتل رزرو کردیم."},{"de":"Sie macht eine Doppelausbildung als Köchin und Konditorin.","en":"She is doing a double apprenticeship as a chef and pastry cook.","ru":"Она получает двойное образование — повара и кондитера.","vi":"Cô ấy đang được đào tạo kép với tư cách là đầu bếp và đầu bếp bánh ngọt.","fa":"او در حال انجام آموزش دوگانه به عنوان آشپز و شیرینی پز است."},{"de":"Das Wort hat hier eine Doppelbedeutung.","en":"The word has a double meaning here.","ru":"Слово здесь имеет двойное значение.","vi":"Từ này có một ý nghĩa kép ở đây.","fa":"این کلمه در اینجا معنایی دوگانه دارد."}]},{"word":"doppelt","en":"double","ru":"двойной","vi":"gấp đôi","fa":"دو برابر کردن","examples":[{"de":"Er verdient doppelt so viel wie ich.","en":"He earns twice as much as I do.","ru":"Он зарабатывает вдвое больше меня.","vi":"Anh ấy kiếm được gấp đôi tôi.","fa":"او دو برابر من درآمد دارد."},{"de":"Bitte schicken Sie mir das Formular in doppelter Ausfertigung.","en":"Please send me the form in duplicate.","ru":"Пожалуйста, пришлите мне бланк в двух экземплярах.","vi":"Xin vui lòng gửi cho tôi mẫu đơn trùng lặp.","fa":"لطفا فرم را در دو نسخه برای من ارسال کنید."}]},{"word":"das Dorf","en":"village","ru":"деревня","vi":"ngôi làng","fa":"روستا","examples":[{"de":"Meine Großeltern wohnen in einem kleinen Dorf.","en":"My grandparents live in a small village.","ru":"Мои бабушка и дедушка живут в маленькой деревне.","vi":"Ông bà tôi sống ở một ngôi làng nhỏ.","fa":"پدربزرگ و مادربزرگ من در یک روستای کوچک زندگی می کنند."},{"de":"Das Dorf hat nur 200 Einwohner.","en":"The village has only 200 inhabitants.","ru":"В деревне всего 200 жителей.","vi":"Ngôi làng chỉ có 200 cư dân.","fa":"این روستا تنها 200 نفر سکنه دارد."}]},{"word":"dort","en":"there","ru":"там","vi":"ở đó","fa":"وجود دارد","examples":[{"de":"Siehst du das Haus? Dort wohne ich.","en":"Do you see that house? I live there.","ru":"Видишь тот дом? Там я живу.","vi":"Bạn có thấy ngôi nhà không? Tôi sống ở đó.","fa":"خانه را می بینی؟ من آنجا زندگی می کنم."},{"de":"Wir fahren nach Italien und bleiben dort zwei Wochen.","en":"We're going to Italy and staying there for two weeks.","ru":"Мы едем в Италию и останемся там на две недели.","vi":"Chúng tôi sẽ đến Ý và ở đó hai tuần.","fa":"ما به ایتالیا می رویم و دو هفته آنجا می مانیم."}]},{"word":"die Dose","en":"can, tin","ru":"банка, консервная банка","vi":"cái lon","fa":"قوطی","examples":[{"de":"Kannst du mir bitte eine Dose Tomaten geben?","en":"Can you give me a can of tomatoes, please?","ru":"Можешь дать мне банку помидоров, пожалуйста?","vi":"Bạn có thể vui lòng cho tôi một lon cà chua được không?","fa":"لطفا یک قوطی گوجه فرنگی به من بدهید؟"},{"de":"Er trinkt die Cola direkt aus der Dose.","en":"He drinks the cola straight from the can.","ru":"Он пьёт колу прямо из банки.","vi":"Anh ta uống Coke trực tiếp từ lon.","fa":"او کوکاکولا را مستقیماً از قوطی می نوشد."}]},{"word":"draußen","en":"outside","ru":"снаружи, на улице","vi":"bên ngoài","fa":"خارج","examples":[{"de":"Es ist kalt, zieh dir draußen eine Jacke an.","en":"It's cold, put on a jacket outside.","ru":"На улице холодно, надень куртку.","vi":"Trời lạnh, mặc áo khoác ra ngoài.","fa":"هوا سرد است، بیرون یک ژاکت بپوش."},{"de":"Die Kinder spielen draußen im Garten.","en":"The children are playing outside in the garden.","ru":"Дети играют на улице в саду.","vi":"Bọn trẻ đang chơi ngoài vườn.","fa":"بچه ها بیرون در باغ بازی می کنند."}]},{"word":"der Dreck","en":"dirt","ru":"грязь","vi":"bụi bẩn","fa":"خاک","examples":[{"de":"Nach der Wanderung war ich voller Dreck.","en":"After the hike I was covered in dirt.","ru":"После похода я был весь в грязи.","vi":"Sau khi đi bộ đường dài, người tôi đầy bụi bẩn.","fa":"بعد از پیاده روی من در خاک پوشیده شده بودم."},{"de":"Mach bitte den Dreck von der Straße weg.","en":"Please clean up the dirt from the street.","ru":"Пожалуйста, убери грязь с улицы.","vi":"Hãy dọn sạch bụi bẩn trên đường phố.","fa":"لطفا خاک را از خیابان پاک کنید."}]},{"word":"drehen","en":"to turn, to rotate; to film/shoot","ru":"вертеть, поворачивать; снимать (фильм)","vi":"xoay","fa":"چرخاندن","examples":[{"de":"Er dreht den Schlüssel im Schloss.","en":"He turns the key in the lock.","ru":"Он поворачивает ключ в замке.","vi":"Anh vặn chìa khóa vào ổ.","fa":"کلید را در قفل می چرخاند."},{"de":"Der Regisseur dreht einen neuen Film.","en":"The director is shooting a new film.","ru":"Режиссёр снимает новый фильм.","vi":"Đạo diễn đang làm một bộ phim mới.","fa":"این کارگردان در حال ساخت فیلم جدیدی است."}]},{"word":"drin","en":"inside, in it","ru":"внутри, там внутри","vi":"bên trong","fa":"داخل","examples":[{"de":"Ist noch Milch drin? – Nein, die Flasche ist leer.","en":"Is there still milk in it? – No, the bottle is empty.","ru":"Там ещё есть молоко? — Нет, бутылка пустая.","vi":"Có còn sữa trong đó không? – Không, chai rỗng rồi.","fa":"آیا هنوز شیر در آن وجود دارد؟ - نه، بطری خالی است."},{"de":"Bleib doch drin, draußen regnet es.","en":"Stay inside, it's raining outside.","ru":"Оставайся внутри, на улице дождь.","vi":"Ở trong nhà đi, ngoài trời đang mưa.","fa":"داخل بمون بیرون بیرون بارون میاد"}]},{"word":"dringend","en":"urgent, urgently","ru":"срочный, срочно","vi":"khẩn cấp","fa":"فوری","examples":[{"de":"Ich brauche dringend deine Hilfe.","en":"I urgently need your help.","ru":"Мне срочно нужна твоя помощь.","vi":"Tôi rất cần sự giúp đỡ của bạn.","fa":"من به کمک شما فوری نیاز دارم."},{"de":"Das ist eine dringende Angelegenheit.","en":"This is an urgent matter.","ru":"Это срочное дело.","vi":"Đây là một vấn đề khẩn cấp.","fa":"این یک موضوع فوری است."}]},{"word":"die Droge","en":"drug","ru":"наркотик","vi":"thuốc","fa":"دارو","examples":[{"de":"Drogen sind in Deutschland zum größten Teil verboten.","en":"Drugs are mostly illegal in Germany.","ru":"Наркотики в Германии в основном запрещены.","vi":"Thuốc hầu hết bị cấm ở Đức.","fa":"مواد مخدر بیشتر در آلمان ممنوع است."},{"de":"Er hat nie im Leben Drogen genommen.","en":"He has never taken drugs in his life.","ru":"Он никогда в жизни не принимал наркотики.","vi":"Anh ấy chưa bao giờ sử dụng ma túy trong đời.","fa":"او هرگز در زندگی خود مواد مخدر مصرف نکرده است."}]},{"word":"die Drogerie","en":"drugstore","ru":"магазин дрогери (хозяйственно-косметический)","vi":"hiệu thuốc","fa":"داروخانه","examples":[{"de":"Ich kaufe Shampoo und Zahnpasta in der Drogerie.","en":"I buy shampoo and toothpaste at the drugstore.","ru":"Я покупаю шампунь и зубную пасту в дрогери.","vi":"Tôi mua dầu gội và kem đánh răng ở hiệu thuốc.","fa":"من شامپو و خمیر دندان را از داروخانه می خرم."},{"de":"Die Drogerie um die Ecke hat lange geöffnet.","en":"The drugstore around the corner is open late.","ru":"Магазин дрогери за углом работает допоздна.","vi":"Hiệu thuốc gần góc phố mở cửa muộn.","fa":"داروخانه این گوشه تا دیروقت باز است."}]},{"word":"drüben","en":"over there","ru":"там, на той стороне","vi":"đằng kia","fa":"اونجا","examples":[{"de":"Meine Tante wohnt drüben, auf der anderen Straßenseite.","en":"My aunt lives over there, on the other side of the street.","ru":"Моя тётя живёт там, на другой стороне улицы.","vi":"Dì tôi sống ở đằng kia, bên kia đường.","fa":"عمه من آنجا زندگی می کند، آن طرف خیابان."},{"de":"Früher lebten meine Großeltern drüben in Ostdeutschland.","en":"In the past my grandparents lived over there in East Germany.","ru":"Раньше мои бабушка и дедушка жили там, в Восточной Германии.","vi":"Ông bà tôi từng sống ở Đông Đức.","fa":"پدربزرگ و مادربزرگ من قبلاً در آلمان شرقی زندگی می کردند."}]},{"word":"drucken","en":"to print","ru":"печатать (на принтере/в типографии)","vi":"in","fa":"چاپ کنید","examples":[{"de":"Kannst du mir das Dokument drucken?","en":"Can you print the document for me?","ru":"Можешь распечатать мне этот документ?","vi":"Bạn có thể in tài liệu cho tôi được không?","fa":"آیا می توانید سند را برای من چاپ کنید؟"},{"de":"Die Zeitung wird jeden Morgen neu gedruckt.","en":"The newspaper is printed fresh every morning.","ru":"Газета печатается заново каждое утро.","vi":"Báo được in lại vào mỗi buổi sáng.","fa":"روزنامه هر روز صبح تجدید چاپ می شود."}]},{"word":"drücken","en":"to press, to push","ru":"нажимать, давить","vi":"nhấn","fa":"را فشار دهید","examples":[{"de":"Bitte drücken Sie den grünen Knopf.","en":"Please press the green button.","ru":"Пожалуйста, нажмите зелёную кнопку.","vi":"Vui lòng nhấn nút màu xanh lá cây.","fa":"لطفا دکمه سبز رنگ را فشار دهید."},{"de":"Die neuen Schuhe drücken mich am Fuß.","en":"The new shoes are pinching my foot.","ru":"Новые туфли жмут мне ногу.","vi":"Đôi giày mới đè nặng lên đôi chân tôi.","fa":"کفش های جدید روی پاهایم سنگینی می کنند."}]},{"word":"der DTZ","en":"DTZ (German Test for Immigrants)","ru":"DTZ (тест по немецкому для мигрантов)","vi":"DTZ","fa":"DTZ","examples":[{"de":"Für die Einbürgerung musst du den DTZ bestehen.","en":"For naturalisation you have to pass the DTZ.","ru":"Для получения гражданства нужно сдать DTZ.","vi":"Để nhập tịch, bạn phải vượt qua DTZ.","fa":"برای تابعیت باید DTZ را بگذرانید."},{"de":"Der DTZ prüft das Sprachniveau A2 bis B1.","en":"The DTZ tests language levels A2 to B1.","ru":"DTZ проверяет уровни языка от A2 до B1.","vi":"DTZ kiểm tra trình độ ngôn ngữ từ A2 đến B1.","fa":"DTZ سطوح زبان A2 تا B1 را آزمایش می کند."},{"de":"Sie hat den DTZ mit einem guten Ergebnis abgeschlossen.","en":"She completed the DTZ with a good result.","ru":"Она прошла DTZ с хорошим результатом.","vi":"Cô ấy đã hoàn thành DTZ với kết quả tốt.","fa":"او DTZ را با نتایج خوبی به پایان رساند."}]},{"word":"dumm","en":"stupid","ru":"глупый","vi":"ngu ngốc","fa":"احمق","examples":[{"de":"Das war eine ziemlich dumme Idee.","en":"That was a pretty stupid idea.","ru":"Это была довольно глупая идея.","vi":"Đó là một ý tưởng khá ngu ngốc.","fa":"این یک ایده کاملا احمقانه بود."},{"de":"Er fühlte sich dumm, weil er die Antwort nicht wusste.","en":"He felt stupid because he didn't know the answer.","ru":"Он чувствовал себя глупо, потому что не знал ответа.","vi":"Anh cảm thấy thật ngu ngốc vì không biết câu trả lời.","fa":"او احساس حماقت می کرد زیرا جواب را نمی دانست."}]},{"word":"dunkel","en":"dark","ru":"тёмный","vi":"tối","fa":"تاریک","examples":[{"de":"Im Winter wird es früh dunkel.","en":"In winter it gets dark early.","ru":"Зимой рано темнеет.","vi":"Vào mùa đông trời tối sớm.","fa":"در زمستان هوا زود تاریک می شود."},{"de":"Sie trägt gern dunkle Kleidung.","en":"She likes to wear dark clothes.","ru":"Она любит носить тёмную одежду.","vi":"Cô ấy thích mặc quần áo tối màu.","fa":"او دوست دارد لباس های تیره بپوشد."}]},{"word":"dünn","en":"thin","ru":"тонкий, худой","vi":"gầy","fa":"نازک","examples":[{"de":"Das Papier ist sehr dünn.","en":"The paper is very thin.","ru":"Бумага очень тонкая.","vi":"Giấy rất mỏng.","fa":"کاغذ بسیار نازک است."},{"de":"Nach der Krankheit war er ziemlich dünn.","en":"After the illness he was quite thin.","ru":"После болезни он был довольно худым.","vi":"Sau cơn bệnh anh gầy đi rất nhiều.","fa":"بعد از بیماری او کاملاً لاغر شده بود."}]},{"word":"durch","en":"through","ru":"через, сквозь","vi":"thông qua","fa":"از طریق","examples":[{"de":"Wir gehen durch den Park nach Hause.","en":"We're walking through the park to get home.","ru":"Мы идём домой через парк.","vi":"Chúng tôi đi bộ về nhà qua công viên.","fa":"از پارک به خانه می رویم."},{"de":"Das Licht scheint durch das Fenster.","en":"The light shines through the window.","ru":"Свет проникает через окно.","vi":"Ánh sáng chiếu qua cửa sổ.","fa":"نور از پنجره می تابد."}]},{"word":"durcheinander","en":"mixed up, confused","ru":"в беспорядке, растерянный","vi":"lộn xộn","fa":"به هم ریخته","examples":[{"de":"Mein Zimmer ist total durcheinander.","en":"My room is a total mess.","ru":"У меня в комнате полный беспорядок.","vi":"Phòng của tôi hoàn toàn bừa bộn.","fa":"اتاق من کلا به هم ریخته است."},{"de":"Nach der Nachricht war sie ganz durcheinander.","en":"After the news she was completely confused and upset.","ru":"После этой новости она была совершенно растеряна.","vi":"Sau khi nghe tin, cô hoàn toàn bối rối.","fa":"بعد از شنیدن این خبر کاملا گیج شد."}]},{"word":"durchfallen","en":"to fail (an exam), to flunk","ru":"провалиться (на экзамене), не сдать","vi":"rơi qua","fa":"سقوط کردن","examples":[{"de":"Ich habe Angst, dass ich durch die Prüfung durchfalle.","en":"I'm afraid I'll fail the exam.","ru":"Я боюсь, что провалю экзамен.","vi":"Tôi sợ tôi sẽ trượt kỳ thi.","fa":"می ترسم در امتحان مردود شوم."},{"de":"Er ist beim ersten Versuch durchgefallen.","en":"He failed on his first attempt.","ru":"Он провалился с первой попытки.","vi":"Anh ấy đã thất bại trong lần thử đầu tiên.","fa":"او در اولین تلاش شکست خورد."},{"de":"Wenn du nicht lernst, fällst du durch.","en":"If you don't study, you'll fail.","ru":"Если не будешь учиться, провалишься.","vi":"Nếu bạn không học, bạn sẽ thất bại.","fa":"اگر درس نخوانی شکست می خوری."}]},{"word":"der Durchmesser","en":"diameter","ru":"диаметр","vi":"đường kính","fa":"قطر","examples":[{"de":"Der Durchmesser eines Kreises ist doppelt so lang wie der Radius.","en":"The diameter of a circle is twice as long as the radius.","ru":"Диаметр окружности вдвое длиннее радиуса.","vi":"Đường kính của một hình tròn dài gấp đôi bán kính.","fa":"قطر دایره دو برابر شعاع آن است."},{"de":"Das Rohr hat einen Durchmesser von zehn Zentimetern.","en":"The pipe has a diameter of ten centimetres.","ru":"У трубы диаметр десять сантиметров.","vi":"Ống có đường kính mười cm.","fa":"قطر لوله ده سانتی متر است."},{"de":"Sie maß den Durchmesser der Münze mit dem Lineal.","en":"She measured the diameter of the coin with the ruler.","ru":"Она измерила диаметр монеты линейкой.","vi":"Cô đo đường kính của đồng xu bằng thước kẻ.","fa":"قطر سکه را با خط کش اندازه گرفت."}]},{"word":"die Durchsage","en":"announcement","ru":"объявление (по громкой связи)","vi":"thông báo","fa":"اعلامیه","examples":[{"de":"Am Bahnhof hörten wir eine wichtige Durchsage.","en":"At the station we heard an important announcement.","ru":"На вокзале мы услышали важное объявление.","vi":"Tại ga xe lửa, chúng tôi nghe được một thông báo quan trọng.","fa":"در ایستگاه قطار یک اطلاعیه مهم شنیدیم."},{"de":"Die Durchsage im Flugzeug war leider sehr leise.","en":"The announcement on the plane was unfortunately very quiet.","ru":"Объявление в самолёте было, к сожалению, очень тихим.","vi":"Thật không may, thông báo trên máy bay rất im lặng.","fa":"متاسفانه اعلامیه در هواپیما بسیار بی سر و صدا بود."}]},{"word":"der Durchschnitt","en":"average","ru":"среднее значение","vi":"mức trung bình","fa":"میانگین","examples":[{"de":"Im Durchschnitt arbeite ich acht Stunden am Tag.","en":"On average, I work eight hours a day.","ru":"В среднем я работаю восемь часов в день.","vi":"Trung bình tôi làm việc tám giờ một ngày.","fa":"به طور متوسط روزی هشت ساعت کار می کنم."},{"de":"Ihre Note liegt über dem Durchschnitt der Klasse.","en":"Her grade is above the class average.","ru":"Её оценка выше среднего по классу.","vi":"Điểm của bạn cao hơn mức trung bình của lớp.","fa":"نمره شما بالاتر از میانگین کلاس است."}]},{"word":"durchschnittlich","en":"average, on average","ru":"средний, в среднем","vi":"trung bình","fa":"متوسط","examples":[{"de":"Er verdient ein durchschnittliches Gehalt.","en":"He earns an average salary.","ru":"Он получает среднюю зарплату.","vi":"Anh ấy kiếm được mức lương trung bình.","fa":"او حقوق متوسطی می گیرد."},{"de":"Durchschnittlich schlafe ich sieben Stunden pro Nacht.","en":"On average I sleep seven hours a night.","ru":"В среднем я сплю семь часов в сутки.","vi":"Trung bình tôi ngủ bảy tiếng một đêm.","fa":"به طور متوسط ​​شبی هفت ساعت می خوابم."},{"de":"Die durchschnittliche Temperatur lag bei zwanzig Grad.","en":"The average temperature was around twenty degrees.","ru":"Средняя температура была около двадцати градусов.","vi":"Nhiệt độ trung bình là hai mươi độ.","fa":"میانگین دما بیست درجه بود."}]},{"word":"durchsetzen","en":"to assert; to push through","ru":"добиваться; отстаивать","vi":"thi hành","fa":"اجرا کنند","examples":[{"de":"Sie konnte ihre Idee im Team durchsetzen.","en":"She managed to push her idea through in the team.","ru":"Ей удалось отстоять свою идею в команде.","vi":"Cô ấy đã có thể thực hiện ý tưởng của mình trong nhóm.","fa":"او توانست ایده خود را در تیم پیاده کند."},{"de":"Gegen die starke Konkurrenz konnte er sich durchsetzen.","en":"He managed to prevail against the strong competition.","ru":"Он смог одержать верх над сильной конкуренцией.","vi":"Anh ấy đã có thể giành chiến thắng trước sự cạnh tranh mạnh mẽ.","fa":"او توانست در برابر رقابت قدرتمند پیروز شود."}]},{"word":"dürfen","en":"to be allowed to, may","ru":"мочь, иметь разрешение","vi":"được phép","fa":"مجاز است","examples":[{"de":"Hier darf man nicht rauchen.","en":"Smoking is not allowed here.","ru":"Здесь нельзя курить.","vi":"Bạn không được phép hút thuốc ở đây.","fa":"اینجا اجازه سیگار کشیدن ندارید."},{"de":"Darf ich das Fenster öffnen?","en":"May I open the window?","ru":"Можно я открою окно?","vi":"Tôi có thể mở cửa sổ được không?","fa":"آیا می توانم پنجره را باز کنم؟"}]},{"word":"der Durst","en":"thirst","ru":"жажда","vi":"cơn khát","fa":"تشنگی","examples":[{"de":"Nach dem Sport hatte ich großen Durst.","en":"After the workout I was very thirsty.","ru":"После тренировки я сильно хотел пить.","vi":"Sau khi tập thể dục tôi rất khát nước.","fa":"بعد از ورزش خیلی تشنه بودم."},{"de":"Hast du Durst? Ich hole dir ein Glas Wasser.","en":"Are you thirsty? I'll get you a glass of water.","ru":"Ты хочешь пить? Я принесу тебе стакан воды.","vi":"Bạn có khát không? Tôi sẽ lấy cho bạn một cốc nước.","fa":"تشنه هستی؟ برات یه لیوان آب میارم"}]},{"word":"durstig sein","en":"to be thirsty","ru":"испытывать жажду, хотеть пить","vi":"khát nước","fa":"تشنه باش","examples":[{"de":"Nach dem Sport bin ich immer sehr durstig.","en":"After sport I am always very thirsty.","ru":"После спорта мне всегда очень хочется пить.","vi":"Tôi luôn rất khát sau khi tập thể dục.","fa":"من همیشه بعد از ورزش خیلی تشنه هستم."},{"de":"Bist du durstig? Ich hole dir ein Wasser.","en":"Are you thirsty? I will get you some water.","ru":"Хочешь пить? Я принесу тебе воды.","vi":"Bạn có khát không? Tôi sẽ lấy cho bạn ít nước.","fa":"تشنه هستی؟ برات آب بیارم"},{"de":"Die Kinder waren nach dem Spielen hungrig und durstig.","en":"After playing, the children were hungry and thirsty.","ru":"После игры дети хотели есть и пить.","vi":"Trẻ em đói và khát sau khi chơi.","fa":"بچه ها بعد از بازی گرسنه و تشنه بودند."}]},{"word":"duzen","en":"to address informally (with 'du')","ru":"обращаться на «ты»","vi":"xưng hô thân mật (dùng 'du')","fa":"با «تو» خطاب کردن","examples":[{"de":"In dieser Firma duzen sich alle Kollegen.","en":"In this company all colleagues use the informal 'du' with each other.","ru":"В этой компании все коллеги обращаются друг к другу на «ты».","vi":"Ở công ty này, tất cả các đồng nghiệp đều gọi tên nhau.","fa":"در این شرکت همه همکاران با شرایط اسمی هستند."},{"de":"Darf ich Sie duzen, oder bevorzugen Sie 'Sie'?","en":"May I use 'du' with you, or do you prefer 'Sie'?","ru":"Можно я буду обращаться к вам на «ты», или вы предпочитаете «вы»?","vi":"Tôi có thể sử dụng tên của bạn được không, hay bạn thích dùng 'bạn' hơn?","fa":"آیا می توانم از نام کوچک شما استفاده کنم یا \"شما\" را ترجیح می دهید؟"}]},{"word":"die e-card","en":"e-card (electronic health insurance card, Austria)","ru":"электронная карта (напр. медицинская карта в Австрии)","vi":"thẻ điện tử","fa":"کارت الکترونیکی","examples":[{"de":"Vergiss deine e-card nicht, wenn du zum Arzt gehst.","en":"Don't forget your e-card when you go to the doctor.","ru":"Не забудь свою электронную карту, когда пойдёшь к врачу.","vi":"Đừng quên thẻ điện tử của bạn khi bạn đi khám bác sĩ.","fa":"هنگام مراجعه به پزشک کارت الکترونیکی خود را فراموش نکنید."},{"de":"Ohne e-card musst du die Behandlung selbst bezahlen.","en":"Without the e-card you have to pay for the treatment yourself.","ru":"Без электронной карты тебе придётся самому платить за лечение.","vi":"Nếu không có thẻ điện tử, bạn phải tự chi trả chi phí điều trị.","fa":"بدون کارت الکترونیکی باید هزینه درمان را خودتان بپردازید."}]},{"word":"eben","en":"just (now); exactly, precisely","ru":"только что; именно","vi":"chỉ","fa":"فقط","examples":[{"de":"Ich habe eben mit ihr telefoniert.","en":"I just talked to her on the phone.","ru":"Я только что разговаривал с ней по телефону.","vi":"Tôi vừa nói chuyện với cô ấy qua điện thoại.","fa":"من فقط تلفنی با او صحبت کردم."},{"de":"Das ist eben das Problem.","en":"That's exactly the problem.","ru":"В этом-то и проблема.","vi":"Đó mới là vấn đề.","fa":"فقط مشکل همینه"}]},{"word":"ebenfalls","en":"likewise, also","ru":"также, тоже","vi":"cũng","fa":"همچنین","examples":[{"de":"Ich wünsche dir ebenfalls einen schönen Urlaub.","en":"I wish you a nice vacation as well.","ru":"Желаю и тебе хорошего отпуска.","vi":"Tôi cũng chúc bạn có một kỳ nghỉ vui vẻ.","fa":"من هم برای شما تعطیلات خوبی آرزو می کنم."},{"de":"Er kommt aus Spanien, seine Frau ebenfalls.","en":"He is from Spain, and his wife is too.","ru":"Он из Испании, его жена тоже.","vi":"Anh ấy đến từ Tây Ban Nha, vợ anh ấy cũng vậy.","fa":"او و همسرش از اسپانیا آمده است."}]},{"word":"ebenso","en":"just as, likewise","ru":"так же, точно так же","vi":"tương tự như vậy","fa":"به همین ترتیب","examples":[{"de":"Sie ist ebenso talentiert wie ihr Bruder.","en":"She is just as talented as her brother.","ru":"Она так же талантлива, как её брат.","vi":"Cô ấy cũng tài năng như anh trai mình.","fa":"او به اندازه برادرش با استعداد است."},{"de":"Ich finde den Film ebenso langweilig wie du.","en":"I find the film just as boring as you do.","ru":"Я нахожу этот фильм таким же скучным, как и ты.","vi":"Tôi thấy bộ phim cũng nhàm chán như bạn vậy.","fa":"به نظر من فیلم هم مثل شما خسته کننده است."}]},{"word":"die EC-Karte","en":"debit card (bank card)","ru":"дебетовая карта (банковская карта)","vi":"thẻ EC","fa":"کارت EC","examples":[{"de":"Kann ich hier mit EC-Karte bezahlen?","en":"Can I pay by debit card here?","ru":"Можно здесь расплатиться дебетовой картой?","vi":"Tôi có thể thanh toán bằng thẻ EC ở đây không?","fa":"آیا می توانم با کارت EC اینجا پرداخت کنم؟"},{"de":"Ich habe meine EC-Karte zu Hause vergessen.","en":"I left my debit card at home.","ru":"Я оставил дебетовую карту дома.","vi":"Tôi quên thẻ ghi nợ ở nhà.","fa":"کارت بانکی ام را در خانه فراموش کردم."},{"de":"Bitte stecken Sie Ihre EC-Karte in das Gerät.","en":"Please insert your debit card into the machine.","ru":"Пожалуйста, вставьте карту в аппарат.","vi":"Vui lòng lắp thẻ ghi nợ của bạn vào thiết bị.","fa":"لطفا کارت نقدی خود را در دستگاه قرار دهید."}]},{"word":"die ec-Karte/EC-Karte","en":"debit card","ru":"дебетовая карта","vi":"thẻ EC/thẻ EC","fa":"کارت EC/کارت EC","examples":[{"de":"Ich bezahle meistens mit meiner EC-Karte.","en":"I usually pay with my debit card.","ru":"Обычно я плачу дебетовой картой.","vi":"Tôi thường thanh toán bằng thẻ ghi nợ của mình.","fa":"من معمولا با کارت بانکی پرداخت می کنم."},{"de":"Kann ich hier mit EC-Karte bezahlen?","en":"Can I pay by debit card here?","ru":"Здесь можно расплатиться дебетовой картой?","vi":"Tôi có thể thanh toán bằng thẻ EC ở đây không?","fa":"آیا می توانم با کارت EC اینجا پرداخت کنم؟"}]},{"word":"echt","en":"real, genuine; really","ru":"настоящий; действительно, правда","vi":"thực","fa":"واقعی","examples":[{"de":"Ist das ein echter Diamant?","en":"Is that a real diamond?","ru":"Это настоящий бриллиант?","vi":"Đó có phải là kim cương thật không?","fa":"آیا این یک الماس واقعی است؟"},{"de":"Das war echt ein toller Abend.","en":"That was really a great evening.","ru":"Это был действительно классный вечер.","vi":"Đó thực sự là một buổi tối tuyệt vời.","fa":"آن شب واقعاً عالی بود."}]},{"word":"das Eck","en":"corner","ru":"угол","vi":"góc","fa":"گوشه","examples":[{"de":"Der Kiosk steht am Eck der Straße.","en":"The kiosk is at the corner of the street.","ru":"Киоск стоит на углу улицы.","vi":"Ki-ốt nằm ở góc phố.","fa":"کیوسک نبش خیابان است."},{"de":"Wir treffen uns am Eck vor der Bäckerei.","en":"We're meeting at the corner in front of the bakery.","ru":"Мы встретимся на углу перед булочной.","vi":"Chúng tôi gặp nhau ở góc trước tiệm bánh.","fa":"در گوشه روبروی نانوایی همدیگر را می بینیم."}]},{"word":"die Ecke","en":"corner","ru":"угол","vi":"góc","fa":"گوشه","examples":[{"de":"Das Café ist gleich um die Ecke.","en":"The café is just around the corner.","ru":"Кафе прямо за углом.","vi":"Quán cà phê ở ngay góc đường.","fa":"کافه همین گوشه است."},{"de":"Stell den Tisch in die Ecke des Zimmers.","en":"Put the table in the corner of the room.","ru":"Поставь стол в угол комнаты.","vi":"Đặt cái bàn ở góc phòng.","fa":"میز را در گوشه اتاق قرار دهید."}]},{"word":"eckig","en":"angular, square-shaped","ru":"угловатый, прямоугольный, квадратный","vi":"hình vuông","fa":"مربع","examples":[{"de":"Der Tisch ist eckig, nicht rund.","en":"The table is square, not round.","ru":"Стол квадратный, а не круглый.","vi":"Bàn có hình vuông chứ không phải tròn.","fa":"میز مربع است نه گرد."},{"de":"Sie trägt eine eckige Brille.","en":"She wears angular glasses.","ru":"Она носит очки угловатой формы.","vi":"Cô ấy đeo kính vuông.","fa":"عینک مربعی میزنه"},{"de":"Die Verpackung hat eine eckige Form.","en":"The packaging has an angular shape.","ru":"У упаковки угловатая форма.","vi":"Bao bì có hình vuông.","fa":"بسته بندی به شکل مربع است."}]},{"word":"egal","en":"indifferent, doesn't matter","ru":"всё равно, безразлично","vi":"không vấn đề gì","fa":"مهم نیست","examples":[{"de":"Es ist mir egal, welchen Film wir sehen.","en":"It doesn't matter to me which film we watch.","ru":"Мне всё равно, какой фильм мы посмотрим.","vi":"Tôi không quan tâm chúng ta xem phim gì.","fa":"برایم مهم نیست چه فیلمی می بینیم."},{"de":"Egal was passiert, ich bleibe bei dir.","en":"No matter what happens, I'll stay with you.","ru":"Что бы ни случилось, я останусь с тобой.","vi":"Dù có chuyện gì xảy ra đi chăng nữa, tôi cũng sẽ ở bên em.","fa":"مهم نیست چه اتفاقی می افتد، من با شما می مانم."}]},{"word":"die Ehe","en":"marriage","ru":"брак","vi":"cuộc hôn nhân","fa":"ازدواج","examples":[{"de":"Sie führen seit zwanzig Jahren eine glückliche Ehe.","en":"They have had a happy marriage for twenty years.","ru":"Они уже двадцать лет живут в счастливом браке.","vi":"Họ đã có một cuộc hôn nhân hạnh phúc suốt hai mươi năm.","fa":"بیست سال است که ازدواج شادی داشته اند."},{"de":"Meine Eltern haben ihre Ehe vor 25 Jahren geschlossen.","en":"My parents got married 25 years ago.","ru":"Мои родители заключили брак 25 лет назад.","vi":"Bố mẹ tôi kết hôn cách đây 25 năm.","fa":"پدر و مادرم 25 سال پیش ازدواج کردند."}]},{"word":"eher","en":"rather, sooner","ru":"скорее, раньше","vi":"đúng hơn","fa":"بلکه","examples":[{"de":"Ich bin eher ein ruhiger Mensch.","en":"I am rather a quiet person.","ru":"Я скорее спокойный человек.","vi":"Tôi là người trầm lặng hơn.","fa":"من بیشتر آدم ساکتی هستم."},{"de":"Komm doch eher, dann haben wir mehr Zeit.","en":"Come sooner, then we'll have more time.","ru":"Приходи пораньше, тогда у нас будет больше времени.","vi":"Hãy đến sớm hơn, chúng ta sẽ có nhiều thời gian hơn.","fa":"زودتر بیا، پس وقت بیشتری خواهیم داشت."}]},{"word":"das Ehrenamt","en":"voluntary work; honorary post","ru":"волонтёрская деятельность; общественная должность","vi":"công việc tình nguyện","fa":"کار داوطلبانه","examples":[{"de":"Sie engagiert sich in ihrer Freizeit im Ehrenamt.","en":"In her free time she is involved in voluntary work.","ru":"В свободное время она занимается волонтёрством.","vi":"Cô ấy làm công việc tình nguyện vào thời gian rảnh rỗi.","fa":"او در اوقات فراغت خود کارهای داوطلبانه انجام می دهد."},{"de":"Ein Ehrenamt wird nicht bezahlt.","en":"Voluntary work is unpaid.","ru":"Волонтёрская деятельность не оплачивается.","vi":"Hoạt động tình nguyện không được trả lương.","fa":"داوطلبانه پرداخت نمی شود."}]},{"word":"ehrenamtlich","en":"voluntary, honorary (unpaid)","ru":"добровольный, на общественных началах (неоплачиваемый)","vi":"tự nguyện","fa":"داوطلبانه","examples":[{"de":"Sie arbeitet ehrenamtlich in einem Tierheim.","en":"She works voluntarily at an animal shelter.","ru":"Она работает волонтёром в приюте для животных.","vi":"Cô tình nguyện tại một nơi trú ẩn động vật.","fa":"او در یک پناهگاه حیوانات داوطلب می شود."},{"de":"Viele Menschen engagieren sich ehrenamtlich.","en":"Many people get involved on a voluntary basis.","ru":"Многие люди занимаются волонтёрством.","vi":"Nhiều người làm công việc tình nguyện.","fa":"بسیاری از افراد کار داوطلبانه انجام می دهند."},{"de":"Die Trainer im Verein sind alle ehrenamtlich tätig.","en":"The coaches at the club all work in an honorary capacity.","ru":"Тренеры в клубе все работают на общественных началах.","vi":"Các huấn luyện viên trong câu lạc bộ đều là tình nguyện viên.","fa":"مربیان باشگاه همگی داوطلب هستند."}]},{"word":"ehrgeizig","en":"ambitious","ru":"честолюбивый; амбициозный","vi":"đầy tham vọng","fa":"جاه طلب","examples":[{"de":"Sie ist sehr ehrgeizig und will immer die Beste sein.","en":"She is very ambitious and always wants to be the best.","ru":"Она очень честолюбива и всегда хочет быть лучшей.","vi":"Cô ấy rất tham vọng và luôn muốn trở thành người giỏi nhất.","fa":"او بسیار جاه طلب است و همیشه می خواهد بهترین باشد."},{"de":"Das sind ziemlich ehrgeizige Ziele.","en":"Those are quite ambitious goals.","ru":"Это довольно амбициозные цели.","vi":"Đây là những mục tiêu khá tham vọng.","fa":"اینها اهداف بسیار بلندپروازانه ای هستند."}]},{"word":"ehrlich","en":"honest","ru":"честный","vi":"thành thật mà nói","fa":"صادقانه","examples":[{"de":"Sei ehrlich zu mir und sag die Wahrheit.","en":"Be honest with me and tell the truth.","ru":"Будь со мной честен и скажи правду.","vi":"Hãy thành thật với tôi và nói sự thật.","fa":"با من صادق باش و حقیقت را بگو."},{"de":"Er ist ein sehr ehrlicher Mensch.","en":"He is a very honest person.","ru":"Он очень честный человек.","vi":"Anh ấy là một người rất trung thực.","fa":"او فردی بسیار صادق است."}]},{"word":"das Ei","en":"egg","ru":"яйцо","vi":"quả trứng","fa":"تخم مرغ","examples":[{"de":"Zum Frühstück esse ich gern ein gekochtes Ei.","en":"For breakfast I like to eat a boiled egg.","ru":"На завтрак я люблю есть варёное яйцо.","vi":"Tôi thích ăn trứng luộc vào bữa sáng.","fa":"من دوست دارم صبحانه یک تخم مرغ آب پز بخورم."},{"de":"Für den Kuchen brauchst du drei Eier.","en":"For the cake you need three eggs.","ru":"Для торта тебе нужно три яйца.","vi":"Bạn cần ba quả trứng cho chiếc bánh.","fa":"برای کیک به سه عدد تخم مرغ نیاز دارید."}]},{"word":"die Eifersucht","en":"jealousy","ru":"ревность","vi":"sự ghen tị","fa":"حسادت","examples":[{"de":"Seine Eifersucht belastete die Beziehung.","en":"His jealousy put a strain on the relationship.","ru":"Его ревность омрачала отношения.","vi":"Sự ghen tuông của anh ấy khiến mối quan hệ trở nên căng thẳng.","fa":"حسادت او روابط را تحت فشار قرار داد."},{"de":"Aus Eifersucht sagte sie kein Wort.","en":"Out of jealousy she didn't say a word.","ru":"Из ревности она не сказала ни слова.","vi":"Cô không nói một lời vì ghen tị.","fa":"از روی حسادت حرفی نزد."}]},{"word":"eigen-","en":"own; (as prefix) self-, characteristic","ru":"свой, собственный; (как приставка) само-, особый","vi":"sở hữu","fa":"خود","examples":[{"de":"Jeder Mensch hat seine eigenen Eigenschaften.","en":"Every person has their own characteristics.","ru":"У каждого человека свои особенности.","vi":"Mỗi người đều có những đặc điểm riêng.","fa":"هر فردی ویژگی های خاص خود را دارد."},{"de":"Sein Verhalten wirkt manchmal etwas eigenartig.","en":"His behavior sometimes seems a bit odd.","ru":"Его поведение иногда кажется немного странным.","vi":"Hành vi của anh ấy đôi khi có vẻ hơi kỳ lạ.","fa":"رفتار او گاهی کمی عجیب به نظر می رسد."}]},{"word":"der Eigenbedarf","en":"personal use; owner's own need (esp. for a property)","ru":"личная надобность; собственная нужда (особенно во владельческом праве на жильё)","vi":"nhu cầu của riêng bạn","fa":"نیازهای خودتان","examples":[{"de":"Der Vermieter hat uns wegen Eigenbedarf gekündigt.","en":"The landlord gave us notice because he needs the flat for his own use.","ru":"Хозяин расторг с нами договор, потому что квартира нужна ему самому.","vi":"Chủ nhà đã thông báo cho chúng tôi vì việc sử dụng cá nhân.","fa":"صاحبخانه به دلیل استفاده شخصی به ما اطلاع داد."},{"de":"Die Wohnung wird für den Eigenbedarf des Eigentümers gebraucht.","en":"The flat is needed for the owner's own use.","ru":"Квартира нужна для собственных нужд владельца.","vi":"Căn hộ được sử dụng cho mục đích riêng của chủ sở hữu.","fa":"آپارتمان برای استفاده خود مالک استفاده می شود."},{"de":"Diese Menge Wein ist nur für den Eigenbedarf.","en":"This amount of wine is only for personal use.","ru":"Это количество вина только для личного потребления.","vi":"Số rượu này chỉ dành cho sử dụng cá nhân.","fa":"این مقدار شراب فقط برای استفاده شخصی است."}]},{"word":"eigentlich","en":"actually, in fact","ru":"на самом деле, собственно","vi":"thực sự","fa":"در واقع","examples":[{"de":"Eigentlich wollte ich heute joggen gehen, aber es regnet.","en":"Actually, I wanted to go jogging today, but it's raining.","ru":"На самом деле я хотел сегодня пойти на пробежку, но идёт дождь.","vi":"Thực ra hôm nay tôi muốn chạy bộ nhưng trời đang mưa.","fa":"من واقعاً می خواستم امروز بروم دویدن، اما باران می بارد."},{"de":"Was machst du eigentlich beruflich?","en":"What do you actually do for a living?","ru":"А чем ты, собственно, занимаешься по работе?","vi":"Bạn thực sự làm gì để kiếm sống?","fa":"در واقع برای امرار معاش چه کار می کنید؟"}]},{"word":"eignen","en":"to be suitable, to lend itself (sich eignen)","ru":"подходить, годиться (sich eignen)","vi":"phù hợp","fa":"مناسب","examples":[{"de":"Dieses Buch eignet sich gut für Anfänger.","en":"This book is well suited for beginners.","ru":"Эта книга хорошо подходит для начинающих.","vi":"Cuốn sách này là tốt cho người mới bắt đầu.","fa":"این کتاب برای مبتدیان خوب است."},{"de":"Der Raum eignet sich nicht für große Veranstaltungen.","en":"The room is not suitable for large events.","ru":"Помещение не подходит для крупных мероприятий.","vi":"Phòng không phù hợp cho các sự kiện lớn.","fa":"اتاق برای رویدادهای بزرگ مناسب نیست."},{"de":"Sie eignet sich hervorragend für diese Stelle.","en":"She is excellently suited for this position.","ru":"Она превосходно подходит для этой должности.","vi":"Cô ấy là người lý tưởng cho vị trí này.","fa":"او برای این موقعیت ایده آل است."}]},{"word":"die Eile","en":"hurry, haste","ru":"спешка, торопливость","vi":"sự vội vàng","fa":"عجله","examples":[{"de":"Ich bin gerade in großer Eile.","en":"I am in a great hurry right now.","ru":"Сейчас я очень тороплюсь.","vi":"Bây giờ tôi đang rất vội.","fa":"من الان خیلی عجله دارم"},{"de":"Es hat keine Eile, du kannst dir Zeit lassen.","en":"There is no hurry, you can take your time.","ru":"Спешить некуда, можешь не торопиться.","vi":"Không cần phải vội, bạn có thể dành thời gian.","fa":"عجله ای نیست، می توانید وقت بگذارید."},{"de":"In der Eile habe ich meinen Schlüssel vergessen.","en":"In my haste I forgot my key.","ru":"В спешке я забыл ключ.","vi":"Trong lúc vội vã tôi quên mất chìa khóa.","fa":"در عجله کلیدم را فراموش کردم."}]},{"word":"eilen","en":"to hurry","ru":"спешить","vi":"vội vàng","fa":"عجله","examples":[{"de":"Sie eilte zum Bahnhof, um den Zug nicht zu verpassen.","en":"She hurried to the station so as not to miss the train.","ru":"Она спешила на вокзал, чтобы не опоздать на поезд.","vi":"Cô vội vã đến ga xe lửa để không bị lỡ chuyến tàu.","fa":"او با عجله به سمت ایستگاه قطار رفت تا قطار را از دست ندهد."},{"de":"Die Sache eilt, wir müssen sofort handeln.","en":"The matter is urgent, we have to act immediately.","ru":"Дело срочное, нам нужно действовать немедленно.","vi":"Vấn đề rất cấp bách, chúng ta phải hành động ngay.","fa":"موضوع فوری است، ما باید فورا اقدام کنیم."}]},{"word":"ein","en":"a, an; one","ru":"один; неопределённый артикль (a/an)","vi":"một","fa":"الف","examples":[{"de":"Ich hätte gern ein Brot, bitte.","en":"I'd like a loaf of bread, please.","ru":"Мне, пожалуйста, буханку хлеба.","vi":"Tôi muốn một ít bánh mì, làm ơn.","fa":"من کمی نان می خواهم، لطفا."},{"de":"Er hat nur ein Kind.","en":"He has only one child.","ru":"У него только один ребёнок.","vi":"Anh ấy chỉ có một đứa con.","fa":"او فقط یک فرزند دارد."},{"de":"Ein Tag hat vierundzwanzig Stunden.","en":"A day has twenty-four hours.","ru":"В сутках двадцать четыре часа.","vi":"Một ngày có hai mươi bốn giờ.","fa":"یک روز بیست و چهار ساعت دارد."}]},{"word":"Ein Beispiel dafür ist …","en":"An example of that is … (giving an example)","ru":"Пример тому — … (пример)","vi":"Một ví dụ đó là…","fa":"نمونه آن …","examples":[{"de":"Ein Beispiel dafür ist das Fahrrad statt des Autos.","en":"An example of that is the bike instead of the car.","ru":"Пример тому — велосипед вместо машины.","vi":"Một ví dụ về điều này là xe đạp thay vì ô tô.","fa":"نمونه آن دوچرخه به جای ماشین است."}]},{"word":"ein bisschen","en":"a little; a bit","ru":"немного","vi":"một chút","fa":"کمی","examples":[{"de":"Kannst du mir ein bisschen Zucker geben?","en":"Can you give me a little sugar?","ru":"Ты можешь дать мне немного сахара?","vi":"Bạn có thể cho tôi một ít đường được không?","fa":"میشه شکر بهم بدی"},{"de":"Ich bin ein bisschen müde heute.","en":"I'm a bit tired today.","ru":"Я немного устал сегодня.","vi":"Hôm nay tôi hơi mệt.","fa":"امروز کمی خسته ام."}]},{"word":"Ein Nachteil ist, dass …","en":"One disadvantage is that … (cons)","ru":"Один из недостатков — что … (минусы)","vi":"Một nhược điểm là…","fa":"یکی از معایب این است که…","examples":[{"de":"Ein Nachteil ist, dass es sehr lange dauert.","en":"One disadvantage is that it takes a very long time.","ru":"Один из недостатков — что это занимает очень много времени.","vi":"Một nhược điểm là phải mất một thời gian rất dài.","fa":"یکی از معایب این است که زمان بسیار زیادی طول می کشد."}]},{"word":"(ein) paar","en":"a few; a couple of","ru":"несколько; пара","vi":"(a) ít","fa":"(الف) تعداد کمی","examples":[{"de":"Ich brauche noch ein paar Minuten.","en":"I still need a few minutes.","ru":"Мне нужно ещё несколько минут.","vi":"Tôi cần thêm vài phút nữa.","fa":"من به چند دقیقه دیگر نیاز دارم."},{"de":"Wir haben ein paar Freunde eingeladen.","en":"We invited a few friends.","ru":"Мы пригласили несколько друзей.","vi":"Chúng tôi đã mời một vài người bạn.","fa":"چند تا از دوستان را دعوت کردیم."}]},{"word":"Ein Vorteil ist, dass …","en":"One advantage is that … (pros)","ru":"Одно из преимуществ — что … (плюсы)","vi":"Một lợi thế là…","fa":"یک مزیت این است که…","examples":[{"de":"Ein Vorteil ist, dass man dabei Geld spart.","en":"One advantage is that you save money doing it.","ru":"Одно из преимуществ — что при этом экономишь деньги.","vi":"Một lợi thế là bạn tiết kiệm tiền.","fa":"یک مزیت این است که در پول خود صرفه جویی می کنید."}]},{"word":"das Einatmen","en":"inhaling, breathing in","ru":"вдох, вдыхание","vi":"hít vào","fa":"استنشاق","examples":[{"de":"Beim Einatmen hebst du langsam die Arme.","en":"As you breathe in, you slowly raise your arms.","ru":"На вдохе ты медленно поднимаешь руки.","vi":"Khi bạn hít vào, từ từ nâng cánh tay của bạn lên.","fa":"در حین نفس کشیدن، به آرامی بازوهای خود را بالا بیاورید."},{"de":"Das Einatmen sollte genauso lang sein wie das Ausatmen.","en":"The inhalation should be as long as the exhalation.","ru":"Вдох должен быть таким же долгим, как и выдох.","vi":"Thời gian hít vào phải bằng thời gian thở ra.","fa":"طول دم باید به اندازه بازدم باشد."},{"de":"Sie zählte beim Einatmen bis vier.","en":"She counted to four while breathing in.","ru":"Она считала до четырёх на вдохе.","vi":"Cô đếm đến bốn trong khi hít vào.","fa":"وقتی نفس می کشید تا چهار می شمرد."}]},{"word":"die Einatmung","en":"inhalation","ru":"вдох, вдыхание (как процесс)","vi":"hít phải","fa":"استنشاق","examples":[{"de":"Bei der Einatmung hebst du langsam die Arme.","en":"On the inhalation you slowly raise your arms.","ru":"На вдохе ты медленно поднимаешь руки.","vi":"Khi bạn hít vào, từ từ nâng cánh tay của bạn lên.","fa":"در حین نفس کشیدن، به آرامی بازوهای خود را بالا بیاورید."},{"de":"Die Einatmung sollte tief in den Bauch gehen.","en":"The inhalation should go deep into the belly.","ru":"Вдох должен идти глубоко в живот.","vi":"Hơi thở phải đi sâu vào dạ dày.","fa":"استنشاق باید به عمق معده برود."},{"de":"Verbinde jede Bewegung mit einer Einatmung oder Ausatmung.","en":"Connect each movement with an inhalation or exhalation.","ru":"Связывай каждое движение с вдохом или выдохом.","vi":"Kết nối từng chuyển động với việc hít vào hoặc thở ra.","fa":"هر حرکت را با دم یا بازدم وصل کنید."}]},{"word":"die Einbahnstraße","en":"one-way street","ru":"улица с односторонним движением","vi":"đường một chiều","fa":"خیابان یک طرفه","examples":[{"de":"Achtung, das ist eine Einbahnstraße!","en":"Watch out, this is a one-way street!","ru":"Осторожно, это улица с односторонним движением!","vi":"Hãy cẩn thận, đây là đường một chiều!","fa":"مواظب باشید این یک خیابان یک طرفه است!"},{"de":"Man darf in dieser Einbahnstraße nicht rückwärts fahren.","en":"You are not allowed to drive backwards on this one-way street.","ru":"На этой односторонней улице нельзя ехать задним ходом.","vi":"Bạn không được phép lùi trên đường một chiều này.","fa":"در این خیابان یک طرفه مجاز به عقب رفتن نیستید."}]},{"word":"einbrechen","en":"to break in (burglary)","ru":"вламываться, совершать кражу со взломом","vi":"đột nhập","fa":"شکستن","examples":[{"de":"In der Nacht sind Diebe in unser Haus eingebrochen.","en":"During the night, thieves broke into our house.","ru":"Ночью в наш дом вломились воры.","vi":"Kẻ trộm đột nhập vào nhà chúng tôi vào ban đêm.","fa":"دزدها شبانه وارد خانه ما شدند."},{"de":"Die Polizei warnt: In dieser Gegend wird oft eingebrochen.","en":"The police warn: there are frequent break-ins in this area.","ru":"Полиция предупреждает: в этом районе часто случаются кражи со взломом.","vi":"Cảnh sát cảnh báo: Những vụ đột nhập thường xuyên xảy ra ở khu vực này.","fa":"پلیس هشدار داد: سرقت در این منطقه رایج است."}]},{"word":"der Einbrecher","en":"burglar (male)","ru":"взломщик, грабитель (мужчина)","vi":"tên trộm","fa":"سارق","examples":[{"de":"Der Einbrecher ist durch das Fenster ins Haus gekommen.","en":"The burglar got into the house through the window.","ru":"Взломщик проник в дом через окно.","vi":"Tên trộm đột nhập vào nhà qua cửa sổ.","fa":"سارق از پنجره وارد خانه شد."},{"de":"Die Nachbarn haben den Einbrecher gehört.","en":"The neighbours heard the burglar.","ru":"Соседи услышали взломщика.","vi":"Hàng xóm nghe thấy tên trộm.","fa":"همسایه ها صدای سارق را شنیدند."},{"de":"Die Polizei hat den Einbrecher schnell gefasst.","en":"The police caught the burglar quickly.","ru":"Полиция быстро поймала взломщика.","vi":"Cảnh sát nhanh chóng bắt được tên trộm.","fa":"پلیس به سرعت سارق را دستگیر کرد."}]},{"word":"die Einbrecherin","en":"burglar (female)","ru":"взломщица, грабительница (женщина)","vi":"tên trộm","fa":"سارق","examples":[{"de":"Die Einbrecherin wurde von einer Kamera gefilmt.","en":"The burglar was filmed by a camera.","ru":"Взломщицу засняла камера.","vi":"Tên trộm đã bị camera ghi lại.","fa":"سارق توسط دوربین شکار شد."},{"de":"Die Einbrecherin ist über den Balkon eingestiegen.","en":"The burglar climbed in over the balcony.","ru":"Взломщица залезла через балкон.","vi":"Tên trộm đột nhập qua ban công.","fa":"سارق از بالکن وارد شد."},{"de":"Die Polizei sucht eine Einbrecherin mit dunklen Haaren.","en":"The police are looking for a female burglar with dark hair.","ru":"Полиция ищет взломщицу с тёмными волосами.","vi":"Cảnh sát đang truy lùng một tên trộm có mái tóc đen.","fa":"پلیس به دنبال سارق با موهای تیره است."}]},{"word":"der Einbruch","en":"break-in, burglary","ru":"взлом, кража со взломом","vi":"sự đột nhập","fa":"نفوذ در","examples":[{"de":"Letzte Nacht gab es einen Einbruch in unserer Straße.","en":"There was a break-in in our street last night.","ru":"Прошлой ночью на нашей улице был взлом.","vi":"Có một vụ đột nhập trên đường phố của chúng tôi đêm qua.","fa":"دیشب تو خیابون ما یه سرکشی شد."},{"de":"Nach dem Einbruch haben wir ein neues Schloss eingebaut.","en":"After the burglary we fitted a new lock.","ru":"После взлома мы поставили новый замок.","vi":"Sau vụ đột nhập, chúng tôi đã lắp một ổ khóa mới.","fa":"پس از نفوذ، یک قفل جدید نصب کردیم."},{"de":"Die Versicherung zahlt den Schaden nach dem Einbruch.","en":"The insurance pays for the damage after the break-in.","ru":"Страховка оплачивает ущерб после взлома.","vi":"Bảo hiểm sẽ bồi thường thiệt hại sau vụ đột nhập.","fa":"بیمه خسارت پس از سرقت را پرداخت می کند."}]},{"word":"eindeutig","en":"clear, unambiguous","ru":"однозначный","vi":"rõ ràng","fa":"به وضوح","examples":[{"de":"Die Antwort auf diese Frage ist eindeutig.","en":"The answer to this question is clear.","ru":"Ответ на этот вопрос однозначен.","vi":"Câu trả lời cho câu hỏi này là rõ ràng.","fa":"پاسخ این سوال روشن است."},{"de":"Er hat sich eindeutig gegen den Vorschlag ausgesprochen.","en":"He clearly spoke out against the proposal.","ru":"Он однозначно высказался против этого предложения.","vi":"Ông rõ ràng đã phản đối đề xuất này.","fa":"او به وضوح با این پیشنهاد مخالفت کرده است."}]},{"word":"der Eindruck","en":"impression","ru":"впечатление","vi":"ấn tượng","fa":"تصور","examples":[{"de":"Sie hat einen guten Eindruck bei ihrem Chef hinterlassen.","en":"She made a good impression on her boss.","ru":"Она произвела хорошее впечатление на своего начальника.","vi":"Cô ấy đã để lại ấn tượng tốt với sếp của mình.","fa":"او تأثیر خوبی بر رئیس خود گذاشت."},{"de":"Mein erster Eindruck von der Stadt war positiv.","en":"My first impression of the city was positive.","ru":"Моё первое впечатление о городе было положительным.","vi":"Ấn tượng đầu tiên của tôi về thành phố là tích cực.","fa":"اولین برداشت من از شهر مثبت بود."}]},{"word":"eine","en":"a, an; one (feminine)","ru":"одна; неопределённый артикль (женский род)","vi":"một","fa":"یکی","examples":[{"de":"Ich hätte gern eine Tasse Kaffee.","en":"I'd like a cup of coffee.","ru":"Мне, пожалуйста, чашку кофе.","vi":"Tôi muốn một tách cà phê.","fa":"من یک فنجان قهوه می خواهم."},{"de":"Sie hat nur eine Schwester.","en":"She has only one sister.","ru":"У неё только одна сестра.","vi":"Cô chỉ có một người chị.","fa":"او فقط یک خواهر دارد."},{"de":"Eine Woche hat sieben Tage.","en":"A week has seven days.","ru":"В неделе семь дней.","vi":"Một tuần có bảy ngày.","fa":"یک هفته هفت روز دارد."}]},{"word":"einen","en":"a, an; one (masculine accusative)","ru":"один; неопределённый артикль (мужской род, винительный падеж)","vi":"một","fa":"یکی","examples":[{"de":"Ich möchte einen Apfel kaufen.","en":"I'd like to buy an apple.","ru":"Я хочу купить яблоко.","vi":"Tôi muốn mua một quả táo.","fa":"من می خواهم یک سیب بخرم."},{"de":"Er hat einen Hund und eine Katze.","en":"He has a dog and a cat.","ru":"У него есть собака и кошка.","vi":"Anh ấy có một con chó và một con mèo.","fa":"او یک سگ و یک گربه دارد."},{"de":"Gib mir bitte einen Moment.","en":"Please give me a moment.","ru":"Дай мне, пожалуйста, минутку.","vi":"Xin vui lòng cho tôi một chút thời gian.","fa":"لطفا یک لحظه به من فرصت دهید."}]},{"word":"einerseits","en":"on the one hand","ru":"с одной стороны","vi":"một mặt","fa":"از یک طرف","examples":[{"de":"Einerseits möchte ich reisen, andererseits fehlt mir das Geld.","en":"On the one hand I want to travel, on the other hand I lack the money.","ru":"С одной стороны, я хочу путешествовать, с другой — у меня нет денег.","vi":"Một mặt tôi muốn đi du lịch, mặt khác tôi không có tiền.","fa":"از یک طرف می خواهم سفر کنم، از طرف دیگر پول ندارم."},{"de":"Einerseits ist der Job gut bezahlt, aber sehr stressig.","en":"On the one hand, the job pays well, but it's very stressful.","ru":"С одной стороны, работа хорошо оплачивается, но очень напряжённая.","vi":"Một mặt, công việc được trả lương cao nhưng rất căng thẳng.","fa":"از یک طرف، این شغل با دستمزد خوب، اما بسیار پر استرس است."}]},{"word":"Einerseits … andererseits …","en":"On the one hand … on the other hand … (weighing up)","ru":"С одной стороны … с другой стороны … (взвешивание)","vi":"Một mặt… mặt khác…","fa":"از یک طرف… از طرف دیگر…","examples":[{"de":"Einerseits ist es teuer, andererseits sehr bequem.","en":"On the one hand it's expensive, on the other hand very convenient.","ru":"С одной стороны это дорого, с другой — очень удобно.","vi":"Một mặt nó đắt tiền, mặt khác nó rất tiện lợi.","fa":"از یک طرف گران است، از طرف دیگر بسیار راحت است."}]},{"word":"einfach","en":"simple, easy","ru":"простой","vi":"dễ dàng","fa":"آسان","examples":[{"de":"Die Aufgabe war wirklich einfach zu lösen.","en":"The task was really easy to solve.","ru":"Задачу было действительно легко решить.","vi":"Nhiệm vụ thực sự dễ dàng để giải quyết.","fa":"حل این کار واقعاً آسان بود."},{"de":"Ich hätte gern einen einfachen Fahrschein nach München.","en":"I'd like a one-way ticket to Munich.","ru":"Я бы хотел билет в один конец до Мюнхена.","vi":"Tôi muốn một vé một chiều tới Munich.","fa":"من یک بلیط یک طرفه به مونیخ می خواهم."}]},{"word":"die Einfahrt","en":"driveway, entrance (for vehicles)","ru":"въезд","vi":"lối vào","fa":"ورودی","examples":[{"de":"Bitte die Einfahrt nicht zuparken.","en":"Please do not block the driveway with your car.","ru":"Пожалуйста, не загораживайте въезд.","vi":"Vui lòng không đậu xe ở lối đi.","fa":"لطفا در خیابان پارک نکنید."},{"de":"Die Einfahrt zur Garage ist ziemlich eng.","en":"The entrance to the garage is quite narrow.","ru":"Въезд в гараж довольно узкий.","vi":"Lối vào gara khá hẹp.","fa":"ورودی گاراژ کاملاً باریک است."}]},{"word":"der Einfall","en":"idea, brainwave","ru":"идея, замысел, озарение","vi":"ý tưởng","fa":"ایده","examples":[{"de":"Das war wirklich ein guter Einfall von dir.","en":"That was a really good idea of yours.","ru":"Это была действительно хорошая идея с твоей стороны.","vi":"Đó thực sự là một ý tưởng hay của bạn.","fa":"این ایده واقعاً خوب شما بود."},{"de":"Mir kam plötzlich ein toller Einfall.","en":"I suddenly had a great brainwave.","ru":"Меня вдруг осенила отличная мысль.","vi":"Tôi chợt nảy ra một ý tưởng tuyệt vời.","fa":"ناگهان یک ایده عالی به ذهنم رسید."},{"de":"Hast du einen besseren Einfall, wie wir das lösen?","en":"Do you have a better idea of how we can solve this?","ru":"У тебя есть идея получше, как нам это решить?","vi":"Bạn có ý tưởng nào hay hơn về cách chúng ta có thể giải quyết vấn đề này không?","fa":"آیا ایده بهتری دارید که چگونه می توانیم این را حل کنیم؟"}]},{"word":"einfallen","en":"to occur to (someone), to come to mind","ru":"приходить в голову","vi":"xảy ra","fa":"رخ دهد","examples":[{"de":"Mir fällt sein Name gerade nicht ein.","en":"His name doesn't come to my mind right now.","ru":"Мне сейчас не приходит на ум его имя.","vi":"Tôi không thể nhớ tên anh ấy ngay bây giờ.","fa":"الان اسمش یادم نیست"},{"de":"Plötzlich fiel ihr eine gute Idee ein.","en":"Suddenly a good idea occurred to her.","ru":"Внезапно ей пришла в голову хорошая идея.","vi":"Đột nhiên cô nghĩ ra một ý hay.","fa":"ناگهان به فکر یک ایده خوب افتاد."}]},{"word":"der Einfluss","en":"influence","ru":"влияние","vi":"sự ảnh hưởng","fa":"نفوذ","examples":[{"de":"Seine Eltern hatten großen Einfluss auf seine Erziehung.","en":"His parents had a great influence on his upbringing.","ru":"Его родители оказали большое влияние на его воспитание.","vi":"Cha mẹ anh có ảnh hưởng lớn đến sự giáo dục của anh.","fa":"پدر و مادرش تأثیر زیادی در تربیت او داشتند."},{"de":"Sie versucht, keinen Einfluss auf die Entscheidung zu nehmen.","en":"She tries not to exert any influence on the decision.","ru":"Она старается не влиять на это решение.","vi":"Cô cố gắng không ảnh hưởng đến quyết định.","fa":"او سعی می کند در تصمیم گیری تأثیری نداشته باشد."}]},{"word":"einfügen","en":"to insert","ru":"вставлять","vi":"chèn","fa":"درج کنید","examples":[{"de":"Füge bitte ein Bild in das Dokument ein.","en":"Please insert an image into the document.","ru":"Пожалуйста, вставь картинку в документ.","vi":"Vui lòng chèn hình ảnh vào tài liệu.","fa":"لطفا یک تصویر در سند وارد کنید."},{"de":"Man kann den Text einfach kopieren und einfügen.","en":"You can simply copy and paste the text.","ru":"Текст можно просто скопировать и вставить.","vi":"Bạn chỉ có thể sao chép và dán văn bản.","fa":"به سادگی می توانید متن را کپی و پیست کنید."}]},{"word":"einführen","en":"to introduce","ru":"вводить, внедрять","vi":"giới thiệu","fa":"معرفی کنید","examples":[{"de":"Die Regierung will eine neue Steuer einführen.","en":"The government wants to introduce a new tax.","ru":"Правительство хочет ввести новый налог.","vi":"Chính phủ muốn giới thiệu một loại thuế mới.","fa":"دولت می خواهد مالیات جدیدی وضع کند."},{"de":"Er führte mich in die neue Software ein.","en":"He introduced me to the new software.","ru":"Он ознакомил меня с новым программным обеспечением.","vi":"Anh ấy đã giới thiệu cho tôi phần mềm mới.","fa":"نرم افزار جدید را به من معرفی کرد."}]},{"word":"die Einführung","en":"introduction (to a subject); launch","ru":"введение (в предмет); внедрение, запуск","vi":"phần giới thiệu","fa":"مقدمه","examples":[{"de":"Am ersten Tag gab es eine kurze Einführung in das Programm.","en":"On the first day there was a short introduction to the programme.","ru":"В первый день было короткое введение в программу.","vi":"Vào ngày đầu tiên có phần giới thiệu ngắn gọn về chương trình.","fa":"در روز اول یک مقدمه کوتاه برای برنامه وجود داشت."},{"de":"Die Einführung des neuen Systems war kompliziert.","en":"The introduction of the new system was complicated.","ru":"Внедрение новой системы было сложным.","vi":"Việc giới thiệu hệ thống mới rất phức tạp.","fa":"معرفی سیستم جدید پیچیده بود."},{"de":"Das Buch beginnt mit einer guten Einführung in das Thema.","en":"The book begins with a good introduction to the subject.","ru":"Книга начинается с хорошего введения в тему.","vi":"Cuốn sách bắt đầu với phần giới thiệu hay về chủ đề này.","fa":"کتاب با یک مقدمه خوب برای موضوع شروع می شود."}]},{"word":"der Eingang","en":"entrance","ru":"вход","vi":"lối vào","fa":"ورودی","examples":[{"de":"Der Eingang zum Museum ist auf der linken Seite.","en":"The entrance to the museum is on the left side.","ru":"Вход в музей находится с левой стороны.","vi":"Lối vào bảo tàng nằm ở bên trái.","fa":"ورودی موزه در سمت چپ است."},{"de":"Bitte warten Sie am Eingang auf mich.","en":"Please wait for me at the entrance.","ru":"Пожалуйста, подождите меня у входа.","vi":"Vui lòng đợi tôi ở lối vào.","fa":"لطفا در ورودی منتظر من باشید."}]},{"word":"eingeben","en":"to enter or type in (data); separable verb","ru":"вводить, вписывать (данные); отделяемый глагол","vi":"nhập","fa":"وارد کنید","examples":[{"de":"Man muss seine persönlichen Daten eingeben.","en":"You have to enter your personal details.","ru":"Нужно ввести свои личные данные.","vi":"Bạn phải nhập thông tin cá nhân của bạn.","fa":"شما باید اطلاعات شخصی خود را وارد کنید."},{"de":"Gib bitte deinen Benutzernamen und dein Passwort ein.","en":"Please enter your username and your password.","ru":"Введи, пожалуйста, своё имя пользователя и пароль.","vi":"Vui lòng nhập tên người dùng và mật khẩu của bạn.","fa":"لطفا نام کاربری و رمز عبور خود را وارد کنید."},{"de":"Ich habe die falsche Adresse eingegeben, deshalb kam das Paket nie an.","en":"I entered the wrong address, so the parcel never arrived.","ru":"Я ввёл неправильный адрес, поэтому посылка так и не пришла.","vi":"Tôi đã nhập sai địa chỉ nên gói hàng không bao giờ đến.","fa":"من آدرس را اشتباه وارد کردم، بنابراین بسته هرگز نرسید."}]},{"word":"einheitlich","en":"uniform, standardized","ru":"единый, единообразный","vi":"đồng phục","fa":"یکنواخت","examples":[{"de":"In der Schule tragen alle Schüler einheitliche Kleidung.","en":"At the school all students wear uniform clothing.","ru":"В этой школе все ученики носят единую форму.","vi":"Ở trường, tất cả học sinh đều mặc đồng phục.","fa":"در مدرسه، همه دانش آموزان لباس یکنواخت می پوشند."},{"de":"Die Preise sind in ganz Europa nicht einheitlich.","en":"Prices are not standardized throughout Europe.","ru":"Цены по всей Европе не единообразны.","vi":"Giá cả không đồng đều trên khắp châu Âu.","fa":"قیمت ها در سراسر اروپا یکسان نیست."}]},{"word":"einig-","en":"some (stem of 'einige')","ru":"некоторые, несколько","vi":"đồng ý-","fa":"موافقت -","examples":[{"de":"Ich habe einige Fragen zu diesem Thema.","en":"I have some questions about this topic.","ru":"У меня есть несколько вопросов по этой теме.","vi":"Tôi có một số câu hỏi về chủ đề này.","fa":"من چند سوال در مورد این موضوع دارم."},{"de":"Einige Leute waren mit der Entscheidung nicht zufrieden.","en":"Some people were not satisfied with the decision.","ru":"Некоторые люди были недовольны этим решением.","vi":"Một số người không hài lòng với quyết định này.","fa":"برخی از مردم از این تصمیم راضی نبودند."}]},{"word":"einigen","en":"to agree, to reach an agreement (sich einigen)","ru":"договариваться, приходить к соглашению (sich einigen)","vi":"một số","fa":"برخی","examples":[{"de":"Wir konnten uns auf einen Termin einigen.","en":"We were able to agree on a date.","ru":"Нам удалось договориться о дате.","vi":"Chúng tôi đã có thể đồng ý về một ngày.","fa":"توانستیم بر سر یک تاریخ به توافق برسیم."},{"de":"Die beiden Parteien haben sich endlich geeinigt.","en":"The two parties have finally reached an agreement.","ru":"Обе стороны наконец пришли к соглашению.","vi":"Hai bên cuối cùng đã đạt được thỏa thuận.","fa":"دو طرف بالاخره به توافق رسیدند."},{"de":"Lasst uns auf einen Kompromiss einigen.","en":"Let's agree on a compromise.","ru":"Давайте сойдёмся на компромиссе.","vi":"Hãy đồng ý về một thỏa hiệp.","fa":"بیایید بر سر یک مصالحه به توافق برسیم."}]},{"word":"einigermaßen","en":"fairly, reasonably, more or less","ru":"более-менее, сносно, в известной мере","vi":"ở một mức độ nào đó","fa":"تا حدی","examples":[{"de":"Mir geht es einigermaßen gut.","en":"I'm doing reasonably well.","ru":"У меня дела идут более-менее нормально.","vi":"Tôi đang làm khá tốt.","fa":"من در حد معقولی خوب هستم."},{"de":"Das Wetter war einigermaßen schön.","en":"The weather was fairly nice.","ru":"Погода была более-менее хорошая.","vi":"Thời tiết khá đẹp.","fa":"هوا نسبتا خوب بود"},{"de":"Er spricht einigermaßen gut Deutsch.","en":"He speaks German reasonably well.","ru":"Он более-менее хорошо говорит по-немецки.","vi":"Anh ấy nói tiếng Đức khá tốt.","fa":"او آلمانی را خوب صحبت می کند."}]},{"word":"der Einkauf","en":"shopping, purchase","ru":"покупки, закупка","vi":"việc mua hàng","fa":"خرید","examples":[{"de":"Der Einkauf für die Woche hat lange gedauert.","en":"The shopping for the week took a long time.","ru":"Покупки на неделю заняли много времени.","vi":"Mua sắm trong tuần mất một thời gian dài.","fa":"خرید برای یک هفته زمان زیادی طول کشید."},{"de":"Kannst du den Einkauf aus dem Auto holen?","en":"Can you fetch the shopping from the car?","ru":"Можешь принести покупки из машины?","vi":"Bạn có thể mang đồ mua sắm ra khỏi xe được không?","fa":"آیا می توانید خرید را از ماشین خارج کنید؟"},{"de":"Beim Einkauf habe ich das Obst vergessen.","en":"I forgot the fruit during the shopping.","ru":"Во время покупок я забыл фрукты.","vi":"Tôi quên trái cây khi đi mua sắm.","fa":"وقتی رفتم خرید میوه رو فراموش کردم."}]},{"word":"einkaufen","en":"to shop, to buy groceries","ru":"делать покупки, ходить за покупками","vi":"mua sắm","fa":"خرید","examples":[{"de":"Samstags gehe ich immer im Supermarkt einkaufen.","en":"On Saturdays I always go grocery shopping at the supermarket.","ru":"По субботам я всегда хожу за покупками в супермаркет.","vi":"Tôi luôn đi mua sắm ở siêu thị vào thứ Bảy.","fa":"من همیشه شنبه ها از سوپرمارکت خرید می کنم."},{"de":"Kannst du auf dem Heimweg noch Brot einkaufen?","en":"Can you buy some bread on the way home?","ru":"Можешь купить хлеб по дороге домой?","vi":"Bạn có thể mua bánh mì trên đường về nhà không?","fa":"آیا می توانید در راه خانه نان بخرید؟"}]},{"word":"die Einkaufsliste","en":"shopping list","ru":"список покупок","vi":"danh sách mua sắm","fa":"لیست خرید","examples":[{"de":"Ich schreibe vor dem Einkauf immer eine Einkaufsliste.","en":"I always write a shopping list before going shopping.","ru":"Перед походом в магазин я всегда пишу список покупок.","vi":"Tôi luôn viết danh sách mua sắm trước khi đi mua sắm.","fa":"من همیشه قبل از خرید یک لیست خرید می نویسم."},{"de":"Auf der Einkaufsliste fehlt noch Milch.","en":"Milk is still missing from the shopping list.","ru":"В списке покупок ещё не хватает молока.","vi":"Sữa vẫn còn thiếu trong danh sách mua sắm.","fa":"شیر هنوز در لیست خرید وجود ندارد."},{"de":"Vergiss nicht, das Brot auf die Einkaufsliste zu setzen.","en":"Don't forget to put the bread on the shopping list.","ru":"Не забудь внести хлеб в список покупок.","vi":"Đừng quên đưa bánh mì vào danh sách mua sắm.","fa":"فراموش نکنید که نان را در لیست خرید قرار دهید."}]},{"word":"das Einkommen","en":"income","ru":"доход","vi":"thu nhập","fa":"درآمد","examples":[{"de":"Sein monatliches Einkommen liegt über dem Durchschnitt.","en":"His monthly income is above average.","ru":"Его ежемесячный доход выше среднего.","vi":"Thu nhập hàng tháng của anh ấy trên mức trung bình.","fa":"درآمد ماهانه او بالاتر از حد متوسط است."},{"de":"Mit diesem Einkommen kann sie sich keine große Wohnung leisten.","en":"With this income she can't afford a large apartment.","ru":"С таким доходом она не может позволить себе большую квартиру.","vi":"Với mức thu nhập này, cô không đủ khả năng mua một căn hộ lớn.","fa":"با این درآمد او نمی تواند یک آپارتمان بزرگ را بخرد."}]},{"word":"einladen","en":"to invite","ru":"приглашать","vi":"mời","fa":"دعوت کنید","examples":[{"de":"Wir laden dich herzlich zu unserer Hochzeit ein.","en":"We warmly invite you to our wedding.","ru":"Мы сердечно приглашаем тебя на нашу свадьбу.","vi":"Chúng tôi trân trọng mời bạn đến dự đám cưới của chúng tôi.","fa":"ما صمیمانه شما را به عروسی خود دعوت می کنیم."},{"de":"Er hat mich zum Essen eingeladen.","en":"He invited me to dinner.","ru":"Он пригласил меня на ужин.","vi":"Anh ấy mời tôi đi ăn tối.","fa":"او مرا به شام ​​دعوت کرد."}]},{"word":"die Einleitung","en":"introduction (of a text), opening section","ru":"введение (текста), вступительная часть","vi":"phần giới thiệu","fa":"مقدمه","examples":[{"de":"Die Einleitung des Aufsatzes war zu lang.","en":"The introduction of the essay was too long.","ru":"Введение к сочинению было слишком длинным.","vi":"Phần giới thiệu bài viết quá dài.","fa":"مقدمه مقاله خیلی طولانی بود."},{"de":"Schreib eine kurze Einleitung zu deinem Vortrag.","en":"Write a short introduction to your talk.","ru":"Напишите короткое вступление к докладу.","vi":"Viết một đoạn giới thiệu ngắn cho bài thuyết trình của bạn.","fa":"یک مقدمه کوتاه برای ارائه خود بنویسید."},{"de":"In der Einleitung erklärt der Autor sein Thema.","en":"In the introduction the author explains his topic.","ru":"Во введении автор объясняет свою тему.","vi":"Trong phần giới thiệu tác giả giải thích chủ đề của mình.","fa":"نویسنده در مقدمه موضوع خود را توضیح می دهد."}]},{"word":"einmal","en":"once","ru":"однажды, один раз","vi":"một lần","fa":"یک بار","examples":[{"de":"Ich war schon einmal in Paris.","en":"I have already been to Paris once.","ru":"Я уже однажды был в Париже.","vi":"Tôi đã từng đến Paris trước đây.","fa":"من قبلاً به پاریس رفته بودم."},{"de":"Können Sie das bitte noch einmal erklären?","en":"Could you please explain that once more?","ru":"Не могли бы вы объяснить это ещё раз?","vi":"Bạn có thể vui lòng giải thích điều đó một lần nữa?","fa":"میشه لطفا دوباره توضیح بدید؟"}]},{"word":"die Einnahme","en":"income, takings","ru":"доход, выручка","vi":"lượng tiêu thụ","fa":"مصرف","examples":[{"de":"Die Einnahmen des Cafés sind im Sommer höher.","en":"The café's takings are higher in summer.","ru":"Выручка кафе летом выше.","vi":"Thu nhập của quán cà phê cao hơn vào mùa hè.","fa":"درآمد کافه در تابستان بیشتر است."},{"de":"Seine einzige Einnahme ist die Rente.","en":"His only income is his pension.","ru":"Его единственный доход — это пенсия.","vi":"Thu nhập duy nhất của ông là lương hưu.","fa":"تنها درآمد او مستمری است."},{"de":"Wir brauchen mehr Einnahmen, um die Kosten zu decken.","en":"We need more income to cover the costs.","ru":"Нам нужно больше доходов, чтобы покрыть расходы.","vi":"Chúng tôi cần thêm doanh thu để trang trải chi phí.","fa":"برای پوشش هزینه ها به درآمد بیشتری نیاز داریم."}]},{"word":"einnehmen","en":"to take (medicine); to occupy","ru":"принимать (лекарство); занимать","vi":"lấy","fa":"گرفتن","examples":[{"de":"Nehmen Sie diese Tabletten dreimal täglich ein.","en":"Take these tablets three times a day.","ru":"Принимайте эти таблетки три раза в день.","vi":"Uống những viên thuốc này ba lần một ngày.","fa":"این قرص ها را سه بار در روز مصرف کنید."},{"de":"Die Firma nimmt eine führende Position auf dem Markt ein.","en":"The company occupies a leading position in the market.","ru":"Компания занимает лидирующую позицию на рынке.","vi":"Công ty chiếm vị trí dẫn đầu trên thị trường.","fa":"این شرکت جایگاه پیشرو در بازار را به خود اختصاص داده است."}]},{"word":"einpacken","en":"to pack, to wrap","ru":"упаковывать","vi":"đóng gói","fa":"بسته بندی کردن","examples":[{"de":"Vergiss nicht, deine Badesachen einzupacken.","en":"Don't forget to pack your swimming things.","ru":"Не забудь упаковать свои купальные принадлежности.","vi":"Đừng quên đóng gói đồ bơi của bạn.","fa":"فراموش نکنید که مایو خود را بسته بندی کنید."},{"de":"Die Verkäuferin packte das Geschenk schön ein.","en":"The saleswoman wrapped the gift nicely.","ru":"Продавщица красиво упаковала подарок.","vi":"Cô bán hàng gói quà rất đẹp.","fa":"خانم فروشنده کادو را به زیبایی بسته بندی کرد."}]},{"word":"einrichten","en":"to furnish, to set up","ru":"обустраивать, оборудовать","vi":"thiết lập","fa":"راه اندازی کنید","examples":[{"de":"Wir haben unsere neue Wohnung gemütlich eingerichtet.","en":"We furnished our new apartment cozily.","ru":"Мы уютно обустроили нашу новую квартиру.","vi":"Chúng tôi đã trang bị nội thất tiện nghi cho căn hộ mới của mình.","fa":"ما آپارتمان جدید خود را به راحتی مبله کرده ایم."},{"de":"Die Firma will ein neues Büro einrichten.","en":"The company wants to set up a new office.","ru":"Компания хочет оборудовать новый офис.","vi":"Công ty muốn thành lập một văn phòng mới.","fa":"این شرکت می خواهد دفتر جدیدی راه اندازی کند."}]},{"word":"die Einrichtung","en":"furnishings; facility, institution; setting-up","ru":"обстановка, обустройство; учреждение, заведение","vi":"cơ sở","fa":"تسهیلات","examples":[{"de":"Die Einrichtung der neuen Wohnung war teuer.","en":"Furnishing the new flat was expensive.","ru":"Обустройство новой квартиры обошлось дорого.","vi":"Nội thất căn hộ mới rất tốn kém.","fa":"اثاثیه آپارتمان جدید گران بود."},{"de":"Mir gefällt die moderne Einrichtung des Cafés.","en":"I like the modern furnishings of the café.","ru":"Мне нравится современная обстановка кафе.","vi":"Tôi thích nội thất hiện đại của quán cà phê.","fa":"من فضای داخلی مدرن کافه را دوست دارم."},{"de":"Das Krankenhaus ist eine wichtige öffentliche Einrichtung.","en":"The hospital is an important public institution.","ru":"Больница — важное общественное учреждение.","vi":"Bệnh viện là một cơ sở công cộng quan trọng.","fa":"بیمارستان یک مرکز عمومی مهم است."}]},{"word":"eins","en":"one","ru":"один (число)","vi":"một","fa":"یکی","examples":[{"de":"Ich nehme nur eins von den Stücken.","en":"I'll take just one of the pieces.","ru":"Я возьму только один из кусочков.","vi":"Tôi sẽ chỉ lấy một trong những mảnh.","fa":"من فقط یکی از قطعات را می گیرم."},{"de":"Es ist schon eins Uhr nachmittags.","en":"It's already one o'clock in the afternoon.","ru":"Уже час дня.","vi":"Bây giờ đã là một giờ chiều.","fa":"الان ساعت یک بعد از ظهر است."},{"de":"Eins plus eins ist zwei.","en":"One plus one is two.","ru":"Один плюс один — два.","vi":"Một cộng một bằng hai.","fa":"یک بعلاوه یک برابر دو است."}]},{"word":"einsam","en":"lonely","ru":"одинокий","vi":"cô đơn","fa":"تنها","examples":[{"de":"Seit dem Umzug fühlt er sich oft einsam.","en":"Since the move he often feels lonely.","ru":"После переезда он часто чувствует себя одиноким.","vi":"Kể từ khi chuyển đi, anh thường cảm thấy cô đơn.","fa":"از زمان نقل مکان، او اغلب احساس تنهایی کرده است."},{"de":"Alte Menschen sind manchmal sehr einsam.","en":"Elderly people are sometimes very lonely.","ru":"Пожилые люди иногда очень одиноки.","vi":"Người già đôi khi rất cô đơn.","fa":"افراد مسن گاهی خیلی تنها هستند."}]},{"word":"einschalten","en":"to switch on","ru":"включать","vi":"bật lên","fa":"روشن کن","examples":[{"de":"Bitte schalte das Licht ein, es ist dunkel.","en":"Please switch on the light, it's dark.","ru":"Пожалуйста, включи свет, темно.","vi":"Làm ơn bật đèn lên, trời tối quá.","fa":"لطفا چراغ ها را روشن کنید، تاریک است."},{"de":"Er schaltete den Fernseher ein, um die Nachrichten zu sehen.","en":"He switched on the TV to watch the news.","ru":"Он включил телевизор, чтобы посмотреть новости.","vi":"Anh bật TV để xem tin tức.","fa":"برای تماشای اخبار تلویزیون را روشن کرد."}]},{"word":"einschließlich","en":"including","ru":"включая, включительно","vi":"bao gồm cả","fa":"از جمله","examples":[{"de":"Der Preis beträgt 50 Euro, einschließlich Frühstück.","en":"The price is 50 euros, including breakfast.","ru":"Цена составляет 50 евро, включая завтрак.","vi":"Giá là 50 euro, bao gồm bữa sáng.","fa":"قیمت 50 یورو با احتساب صبحانه."},{"de":"Das Museum ist von Montag einschließlich Freitag geöffnet.","en":"The museum is open from Monday through Friday, inclusive.","ru":"Музей открыт с понедельника по пятницу включительно.","vi":"Bảo tàng mở cửa từ thứ Hai đến thứ Sáu.","fa":"موزه از دوشنبه تا جمعه باز است."}]},{"word":"das Einschreiben","en":"registered letter/mail","ru":"заказное письмо","vi":"thư đã đăng ký","fa":"نامه ثبت شده","examples":[{"de":"Ich habe den Brief als Einschreiben verschickt.","en":"I sent the letter by registered mail.","ru":"Я отправил письмо заказным.","vi":"Tôi đã gửi thư dưới dạng thư bảo đảm.","fa":"من نامه را به صورت پست سفارشی فرستادم."},{"de":"Für wichtige Dokumente sollte man ein Einschreiben benutzen.","en":"For important documents you should use registered mail.","ru":"Для важных документов следует пользоваться заказным письмом.","vi":"Bạn nên sử dụng thư bảo đảm cho các tài liệu quan trọng.","fa":"برای اسناد مهم باید از پست ثبت شده استفاده کنید."}]},{"word":"einsetzen","en":"to use, to deploy; to insert","ru":"использовать, задействовать; вставлять","vi":"chèn","fa":"درج کنید","examples":[{"de":"Die Firma setzt moderne Technik ein.","en":"The company deploys modern technology.","ru":"Компания использует современные технологии.","vi":"Công ty sử dụng công nghệ hiện đại.","fa":"این شرکت از تکنولوژی مدرن استفاده می کند."},{"de":"Er setzt sich sehr für den Umweltschutz ein.","en":"He is very committed to environmental protection.","ru":"Он активно борется за охрану окружающей среды.","vi":"Anh ấy rất quan tâm đến việc bảo vệ môi trường.","fa":"او به حفاظت از محیط زیست بسیار متعهد است."}]},{"word":"einsparen","en":"to save, to economise on","ru":"экономить (сберегать)","vi":"lưu lại","fa":"ذخیره کنید","examples":[{"de":"Wir wollen im Haushalt viel Energie einsparen.","en":"We want to save a lot of energy in the household.","ru":"Мы хотим сэкономить много энергии в домашнем хозяйстве.","vi":"Chúng tôi muốn tiết kiệm rất nhiều năng lượng trong gia đình.","fa":"ما می خواهیم در مصرف انرژی در خانه صرفه جویی کنیم."},{"de":"Durch das Fahrrad lässt sich viel CO2 einsparen.","en":"A lot of CO2 can be saved by using a bicycle.","ru":"Благодаря велосипеду можно сэкономить много CO2.","vi":"Đi xe đạp có thể tiết kiệm rất nhiều CO2.","fa":"دوچرخه سواری می تواند مقدار زیادی CO2 را ذخیره کند."},{"de":"Die Firma will bis 2030 die Hälfte der Emissionen einsparen.","en":"The company wants to cut half of its emissions by 2030.","ru":"Фирма хочет сократить половину выбросов к 2030 году.","vi":"Công ty muốn tiết kiệm một nửa lượng khí thải vào năm 2030.","fa":"این شرکت می خواهد تا سال 2030 نیمی از انتشار گازهای گلخانه ای خود را کاهش دهد."}]},{"word":"einsteigen","en":"to get in, to board (a vehicle)","ru":"садиться (в транспорт)","vi":"vào trong","fa":"وارد شوید","examples":[{"de":"Bitte einsteigen, der Zug fährt gleich ab!","en":"All aboard, the train is about to depart!","ru":"Просьба заходить, поезд сейчас отправляется!","vi":"Xin mời vào trong, tàu sắp khởi hành rồi!","fa":"لطفا سوار شوید، قطار به زودی حرکت می کند!"},{"de":"Sie stieg schnell in den Bus ein.","en":"She quickly got on the bus.","ru":"Она быстро села в автобус.","vi":"Cô nhanh chóng lên xe buýt.","fa":"سریع سوار اتوبوس شد."}]},{"word":"einstellen","en":"to adjust; to hire; to stop","ru":"настраивать; принимать на работу; прекращать","vi":"đặt","fa":"مجموعه","examples":[{"de":"Die Firma will fünf neue Mitarbeiter einstellen.","en":"The company wants to hire five new employees.","ru":"Компания хочет нанять пять новых сотрудников.","vi":"Công ty muốn thuê năm nhân viên mới.","fa":"این شرکت می خواهد پنج کارمند جدید استخدام کند."},{"de":"Kannst du die Lautstärke etwas leiser einstellen?","en":"Can you turn the volume down a bit?","ru":"Можешь сделать звук немного тише?","vi":"Bạn có thể giảm âm lượng xuống một chút được không?","fa":"میشه یه کم صدا رو کم کنید؟"}]},{"word":"die Einstellung","en":"setting","ru":"настройка","vi":"cài đặt","fa":"تنظیم","examples":[{"de":"Du kannst die Sprache in den Einstellungen ändern.","en":"You can change the language in the settings.","ru":"Язык можно изменить в настройках.","vi":"Bạn có thể thay đổi ngôn ngữ trong cài đặt.","fa":"می توانید زبان را در تنظیمات تغییر دهید."},{"de":"Diese Einstellung schützt deine Privatsphäre.","en":"This setting protects your privacy.","ru":"Эта настройка защищает твою приватность.","vi":"Cài đặt này bảo vệ quyền riêng tư của bạn.","fa":"این تنظیم از حریم خصوصی شما محافظت می کند."},{"de":"Nach dem Update wurden alle Einstellungen zurückgesetzt.","en":"After the update all the settings were reset.","ru":"После обновления все настройки сбросились.","vi":"Sau khi cập nhật, tất cả các cài đặt đã được đặt lại.","fa":"بعد از آپدیت تمام تنظیمات ریست شد."}]},{"word":"eintragen","en":"to enter, to register (in writing)","ru":"вносить (в список/реестр)","vi":"nhập","fa":"وارد کنید","examples":[{"de":"Bitte tragen Sie Ihren Namen in die Liste ein.","en":"Please enter your name in the list.","ru":"Пожалуйста, впишите своё имя в список.","vi":"Hãy thêm tên của bạn vào danh sách.","fa":"لطفا نام خود را به لیست اضافه کنید."},{"de":"Der neue Termin wurde im Kalender eingetragen.","en":"The new appointment was entered in the calendar.","ru":"Новая встреча была внесена в календарь.","vi":"Cuộc hẹn mới đã được nhập vào lịch.","fa":"قرار جدید در تقویم درج شده است."}]},{"word":"eintreten","en":"to enter; to occur","ru":"входить; наступать (о событии)","vi":"nhập","fa":"وارد کنید","examples":[{"de":"Bitte treten Sie ein und nehmen Sie Platz.","en":"Please come in and take a seat.","ru":"Пожалуйста, входите и присаживайтесь.","vi":"Xin mời vào trong và ngồi.","fa":"لطفا بیایید و بنشینید."},{"de":"Falls der Notfall eintritt, rufen Sie sofort an.","en":"If the emergency occurs, call immediately.","ru":"Если наступит чрезвычайная ситуация, звоните немедленно.","vi":"Nếu trường hợp khẩn cấp xảy ra, hãy gọi ngay.","fa":"اگر شرایط اضطراری رخ داد، بلافاصله تماس بگیرید."}]},{"word":"einverstanden","en":"agreed, in agreement","ru":"согласен","vi":"đã đồng ý","fa":"موافقت کرد","examples":[{"de":"Bist du mit meinem Vorschlag einverstanden?","en":"Do you agree with my proposal?","ru":"Ты согласен с моим предложением?","vi":"Bạn có đồng ý với đề nghị của tôi không?","fa":"آیا با پیشنهاد من موافقید؟"},{"de":"Einverstanden, wir treffen uns um sechs Uhr.","en":"Agreed, we'll meet at six o'clock.","ru":"Договорились, встретимся в шесть часов.","vi":"Đồng ý, chúng ta sẽ gặp nhau lúc sáu giờ.","fa":"توافق کردیم، ساعت شش همدیگر را می بینیم."}]},{"word":"der Einwand","en":"objection","ru":"возражение","vi":"sự phản đối","fa":"اعتراض","examples":[{"de":"Hast du einen Einwand gegen meinen Vorschlag?","en":"Do you have an objection to my proposal?","ru":"У вас есть возражения против моего предложения?","vi":"Bạn có phản đối đề nghị của tôi không?","fa":"آیا با پیشنهاد من مخالفتی دارید؟"},{"de":"Sie erhob einen wichtigen Einwand in der Diskussion.","en":"She raised an important objection in the discussion.","ru":"Она высказала важное возражение в обсуждении.","vi":"Cô ấy đã đưa ra một phản đối quan trọng trong cuộc thảo luận.","fa":"او در بحث اعتراض مهمی را مطرح کرد."},{"de":"Wenn niemand einen Einwand hat, machen wir es so.","en":"If no one has an objection, we'll do it like this.","ru":"Если ни у кого нет возражений, мы так и сделаем.","vi":"Nếu không ai phản đối thì chúng ta sẽ làm theo cách này.","fa":"اگر کسی مخالفتی نداشته باشد، این کار را انجام می دهیم."}]},{"word":"der Einwohner","en":"inhabitant, resident","ru":"житель","vi":"cư dân","fa":"ساکنان","examples":[{"de":"Die Stadt hat etwa eine Million Einwohner.","en":"The city has about one million inhabitants.","ru":"В городе проживает около миллиона жителей.","vi":"Thành phố có khoảng một triệu dân.","fa":"این شهر حدود یک میلیون نفر جمعیت دارد."},{"de":"Die Einwohner protestierten gegen den neuen Flughafen.","en":"The residents protested against the new airport.","ru":"Жители протестовали против нового аэропорта.","vi":"Người dân phản đối sân bay mới.","fa":"ساکنان به فرودگاه جدید اعتراض کردند."}]},{"word":"die Einwohnerin","en":"inhabitant, resident (female)","ru":"жительница (женщина)","vi":"cư dân","fa":"ساکن","examples":[{"de":"Als langjährige Einwohnerin kennt sie die Stadt sehr gut.","en":"As a long-standing resident she knows the city very well.","ru":"Как давняя жительница она очень хорошо знает город.","vi":"Là một cư dân lâu năm, cô biết rất rõ về thành phố này.","fa":"به عنوان یک ساکن قدیمی، او شهر را به خوبی می شناسد."},{"de":"Jede Einwohnerin hat das Recht zu wählen.","en":"Every female resident has the right to vote.","ru":"Каждая жительница имеет право голоса.","vi":"Mọi công dân đều có quyền bầu cử.","fa":"هر ساکنی حق رای دارد."},{"de":"Die älteste Einwohnerin des Ortes ist 99 Jahre alt.","en":"The oldest inhabitant of the place is 99 years old.","ru":"Самой старой жительнице этого места 99 лет.","vi":"Cư dân lớn tuổi nhất của thị trấn đã 99 tuổi.","fa":"مسن ترین ساکن این شهر 99 سال سن دارد."}]},{"word":"einzahlen","en":"to pay in; to deposit (money)","ru":"вносить (деньги), класть на счёт","vi":"đặt cọc","fa":"سپرده گذاری","examples":[{"de":"Ich möchte 200 Euro auf mein Konto einzahlen.","en":"I would like to deposit 200 euros into my account.","ru":"Я хотел бы внести 200 евро на свой счёт.","vi":"Tôi muốn gửi 200 euro vào tài khoản của mình.","fa":"من می خواهم 200 یورو به حسابم واریز کنم."},{"de":"Er zahlt jeden Monat einen Teil seines Gehalts ein.","en":"He pays in part of his salary every month.","ru":"Каждый месяц он вносит часть своей зарплаты.","vi":"Anh ấy trả một phần tiền lương hàng tháng.","fa":"او هر ماه بخشی از حقوق خود را پرداخت می کند."}]},{"word":"die Einzahlung","en":"deposit, paying-in (of money)","ru":"внесение денег, вклад (на счёт)","vi":"tiền đặt cọc","fa":"سپرده","examples":[{"de":"Die Einzahlung auf mein Konto war sofort sichtbar.","en":"The deposit into my account showed up immediately.","ru":"Внесение на мой счёт отобразилось сразу.","vi":"Khoản tiền gửi vào tài khoản của tôi được hiển thị ngay lập tức.","fa":"واریز به حساب من بلافاصله قابل مشاهده بود."},{"de":"Für die Einzahlung von Bargeld gibt es einen Automaten.","en":"There is a machine for paying in cash.","ru":"Есть автомат для внесения наличных.","vi":"Có máy ATM để gửi tiền mặt.","fa":"یک دستگاه خودپرداز برای واریز وجه نقد وجود دارد."},{"de":"Bitte bestätigen Sie die Einzahlung von 200 Euro.","en":"Please confirm the deposit of 200 euros.","ru":"Пожалуйста, подтвердите внесение 200 евро.","vi":"Vui lòng xác nhận khoản đặt cọc 200 euro.","fa":"لطفا واریز 200 یورو را تایید کنید."}]},{"word":"die Einzelheit","en":"detail","ru":"деталь, подробность","vi":"chi tiết","fa":"جزئیات","examples":[{"de":"Er hat mir jede Einzelheit der Reise erzählt.","en":"He told me every detail of the trip.","ru":"Он рассказал мне каждую подробность поездки.","vi":"Anh ấy kể cho tôi nghe mọi chi tiết của chuyến đi.","fa":"او تمام جزئیات سفر را به من گفت."},{"de":"Über die Einzelheiten sprechen wir später.","en":"We'll talk about the details later.","ru":"О деталях мы поговорим позже.","vi":"Chúng ta sẽ nói về chi tiết sau.","fa":"بعداً در مورد جزئیات صحبت خواهیم کرد."},{"de":"Bitte achten Sie auf jede Einzelheit im Vertrag.","en":"Please pay attention to every detail in the contract.","ru":"Пожалуйста, обратите внимание на каждую деталь в договоре.","vi":"Hãy chú ý đến từng chi tiết trong hợp đồng.","fa":"لطفا به تمام جزئیات قرارداد توجه کنید."}]},{"word":"einzeln","en":"individual; single","ru":"отдельный, единичный","vi":"cá nhân","fa":"به صورت جداگانه","examples":[{"de":"Die Äpfel werden einzeln verpackt.","en":"The apples are packed individually.","ru":"Яблоки упаковываются по отдельности.","vi":"Táo được đóng gói riêng lẻ.","fa":"سیب ها به صورت تکی بسته بندی می شوند."},{"de":"Kann ich die Teile auch einzeln kaufen?","en":"Can I also buy the parts individually?","ru":"Можно ли купить детали по отдельности?","vi":"Tôi cũng có thể mua từng bộ phận riêng lẻ được không?","fa":"آیا می توانم قطعات را به صورت تکی هم بخرم؟"}]},{"word":"einziehen","en":"to move in (to a home)","ru":"въезжать, переезжать (в жильё)","vi":"chuyển đến","fa":"حرکت کن","examples":[{"de":"Wir ziehen nächste Woche in die neue Wohnung ein.","en":"We are moving into the new apartment next week.","ru":"На следующей неделе мы переезжаем в новую квартиру.","vi":"Chúng tôi sẽ chuyển đến căn hộ mới vào tuần tới.","fa":"هفته آینده به آپارتمان جدید نقل مکان می کنیم."},{"de":"Wann seid ihr in dieses Haus eingezogen?","en":"When did you move into this house?","ru":"Когда вы переехали в этот дом?","vi":"Bạn chuyển đến ngôi nhà này khi nào?","fa":"چه زمانی به این خانه نقل مکان کردید؟"}]},{"word":"einzig","en":"only, sole","ru":"единственный","vi":"chỉ","fa":"فقط","examples":[{"de":"Sie ist die einzige Frau im Team.","en":"She is the only woman on the team.","ru":"Она — единственная женщина в команде.","vi":"Cô ấy là người phụ nữ duy nhất trong đội.","fa":"او تنها زن تیم است."},{"de":"Das war meine einzige Chance, ihn zu treffen.","en":"That was my only chance to meet him.","ru":"Это был мой единственный шанс встретить его.","vi":"Đây là cơ hội duy nhất để tôi gặp anh ấy.","fa":"این تنها فرصت من برای ملاقات با او بود."},{"de":"Kein einziges Wort hat er gesagt.","en":"He didn't say a single word.","ru":"Он не сказал ни единого слова.","vi":"Anh ấy không nói một lời nào.","fa":"حتی یک کلمه هم نگفت."}]},{"word":"einzig-","en":"only, sole (stem meaning 'unique/single')","ru":"единственный (основа со значением 'уникальный')","vi":"chỉ-","fa":"فقط-","examples":[{"de":"Dieses Gemälde ist wirklich einzigartig.","en":"This painting is truly unique.","ru":"Эта картина поистине уникальна.","vi":"Bức tranh này thực sự độc đáo.","fa":"این نقاشی واقعا منحصر به فرد است."},{"de":"Die Landschaft dort ist einzigartig schön.","en":"The landscape there is uniquely beautiful.","ru":"Пейзаж там уникально красив.","vi":"Phong cảnh ở đó đẹp độc đáo.","fa":"مناظر آنجا فوق العاده زیباست."}]},{"word":"das Eis","en":"ice; ice cream","ru":"лёд; мороженое","vi":"kem","fa":"بستنی","examples":[{"de":"Im Winter ist der See mit Eis bedeckt.","en":"In winter the lake is covered with ice.","ru":"Зимой озеро покрыто льдом.","vi":"Vào mùa đông mặt hồ được bao phủ bởi băng.","fa":"در زمستان دریاچه پوشیده از یخ است."},{"de":"Die Kinder essen gern Eis im Sommer.","en":"The children like eating ice cream in summer.","ru":"Дети любят есть мороженое летом.","vi":"Trẻ em thích ăn kem vào mùa hè.","fa":"بچه ها دوست دارند در تابستان بستنی بخورند."}]},{"word":"die Eisenbahn","en":"railway","ru":"железная дорога","vi":"đường sắt","fa":"راه آهن","examples":[{"de":"Die Eisenbahn verbindet die beiden Städte.","en":"The railway connects the two cities.","ru":"Железная дорога соединяет два города.","vi":"Đường sắt kết nối hai thành phố.","fa":"راه آهن این دو شهر را به هم متصل می کند."},{"de":"Früher sind wir oft mit der Eisenbahn gereist.","en":"In the past we often traveled by railway.","ru":"Раньше мы часто путешествовали на поезде.","vi":"Chúng tôi thường đi du lịch bằng tàu hỏa.","fa":"ما اغلب با قطار سفر می کردیم."}]},{"word":"elegant","en":"elegant","ru":"элегантный","vi":"thanh lịch","fa":"ظریف","examples":[{"de":"Sie trägt ein elegantes Kleid zur Feier.","en":"She is wearing an elegant dress to the party.","ru":"Она надела элегантное платье на праздник.","vi":"Cô mặc một chiếc váy thanh lịch cho lễ kỷ niệm.","fa":"او یک لباس شیک برای جشن می پوشد."},{"de":"Das Restaurant ist sehr elegant eingerichtet.","en":"The restaurant is furnished very elegantly.","ru":"Ресторан обставлен очень элегантно.","vi":"Nhà hàng được trang trí rất trang nhã.","fa":"رستوران بسیار شیک تزئین شده است."}]},{"word":"elektrisch","en":"electric","ru":"электрический","vi":"điện","fa":"برقی","examples":[{"de":"Wir haben ein elektrisches Auto gekauft.","en":"We bought an electric car.","ru":"Мы купили электрический автомобиль.","vi":"Chúng tôi đã mua một chiếc xe điện.","fa":"ما یک ماشین برقی خریدیم."},{"de":"Der elektrische Herd funktioniert nicht mehr.","en":"The electric stove no longer works.","ru":"Электрическая плита больше не работает.","vi":"Bếp điện không còn hoạt động nữa.","fa":"اجاق برقی دیگر کار نمی کند."}]},{"word":"elektro-","en":"electro-, electric (combining form, e.g. Elektroauto, Elektrogerät)","ru":"электро-, электрический (в составе слов, напр. Elektroauto, Elektrogerät)","vi":"điện","fa":"برقی","examples":[{"de":"Immer mehr Menschen kaufen sich ein Elektroauto.","en":"More and more people are buying an electric car.","ru":"Всё больше людей покупают электромобиль.","vi":"Ngày càng có nhiều người mua xe điện.","fa":"مردم بیشتر و بیشتر به خرید خودروهای برقی می پردازند."},{"de":"Im Elektrogeschäft gibt es viele neue Geräte.","en":"There are many new devices in the electrical store.","ru":"В магазине электротехники много новых приборов.","vi":"Có rất nhiều thiết bị mới trong cửa hàng điện tử.","fa":"بسیاری از دستگاه های جدید در فروشگاه لوازم الکترونیکی وجود دارد."},{"de":"Alte Elektrogeräte muss man richtig entsorgen.","en":"Old electrical appliances must be disposed of properly.","ru":"Старую электротехнику нужно правильно утилизировать.","vi":"Các thiết bị điện cũ phải được xử lý đúng cách.","fa":"وسایل برقی قدیمی باید به درستی دور ریخته شوند."}]},{"word":"das Elektroauto","en":"electric car","ru":"электромобиль","vi":"xe điện","fa":"ماشین الکتریکی","examples":[{"de":"Immer mehr Menschen fahren ein Elektroauto.","en":"More and more people drive an electric car.","ru":"Всё больше людей ездят на электромобиле.","vi":"Ngày càng có nhiều người lái xe điện.","fa":"روز به روز افراد بیشتری در حال رانندگی با خودروهای برقی هستند."},{"de":"Ein Elektroauto stößt beim Fahren keine Abgase aus.","en":"An electric car emits no exhaust fumes while driving.","ru":"Электромобиль при движении не выделяет выхлопных газов.","vi":"Ôtô điện không thải ra khói thải khi lái xe.","fa":"خودروهای برقی هنگام رانندگی هیچ گونه دود اگزوز ساطع نمی کنند."},{"de":"Wir überlegen, ob wir uns ein Elektroauto kaufen sollen.","en":"We are considering whether we should buy an electric car.","ru":"Мы раздумываем, купить ли нам электромобиль.","vi":"Chúng tôi đang suy nghĩ xem có nên mua một chiếc ô tô điện hay không.","fa":"ما به این فکر می کنیم که آیا باید یک ماشین برقی بخریم یا خیر."}]},{"word":"das Elektron","en":"electron","ru":"электрон","vi":"điện tử","fa":"الکترون","examples":[{"de":"Ein Elektron ist viel leichter als ein Proton.","en":"An electron is much lighter than a proton.","ru":"Электрон гораздо легче протона.","vi":"Electron nhẹ hơn proton rất nhiều.","fa":"یک الکترون بسیار سبکتر از یک پروتون است."},{"de":"Das Elektron bewegt sich um den Atomkern.","en":"The electron moves around the atomic nucleus.","ru":"Электрон движется вокруг атомного ядра.","vi":"Electron chuyển động xung quanh hạt nhân nguyên tử.","fa":"الکترون در اطراف هسته اتم حرکت می کند."},{"de":"Jedes Elektron trägt eine negative Ladung.","en":"Each electron carries a negative charge.","ru":"Каждый электрон несёт отрицательный заряд.","vi":"Mỗi electron mang một điện tích âm.","fa":"هر الکترون حامل بار منفی است."}]},{"word":"elektronisch","en":"electronic","ru":"электронный","vi":"bằng điện tử","fa":"به صورت الکترونیکی","examples":[{"de":"Heute bezahlen wir fast alles auf elektronischem Weg.","en":"Today we pay for almost everything electronically.","ru":"Сегодня мы платим за почти всё электронно.","vi":"Ngày nay chúng ta thanh toán hầu hết mọi thứ bằng điện tử.","fa":"امروزه تقریباً همه چیز را به صورت الکترونیکی پرداخت می کنیم."},{"de":"Die Rechnung bekommen Sie als elektronisches Dokument.","en":"You'll receive the invoice as an electronic document.","ru":"Вы получите счёт в виде электронного документа.","vi":"Bạn sẽ nhận được hóa đơn dưới dạng tài liệu điện tử.","fa":"فاکتور را به عنوان یک سند الکترونیکی دریافت خواهید کرد."},{"de":"In dieser Firma wird alles elektronisch gespeichert.","en":"In this company everything is stored electronically.","ru":"В этой фирме всё хранится в электронном виде.","vi":"Ở công ty này mọi thứ đều được lưu trữ điện tử.","fa":"در این شرکت همه چیز به صورت الکترونیکی ذخیره می شود."}]},{"word":"die Eltern","en":"parents","ru":"родители","vi":"bố mẹ","fa":"والدین","examples":[{"de":"Meine Eltern wohnen auf dem Land.","en":"My parents live in the countryside.","ru":"Мои родители живут в деревне.","vi":"Bố mẹ tôi sống ở quê.","fa":"پدر و مادرم در کشور زندگی می کنند."},{"de":"Ich besuche meine Eltern jedes Wochenende.","en":"I visit my parents every weekend.","ru":"Я навещаю родителей каждые выходные.","vi":"Tôi đến thăm bố mẹ tôi vào mỗi cuối tuần.","fa":"آخر هفته به پدر و مادرم سر می زنم."}]},{"word":"der Elternsprecher","en":"parents' representative (class/school spokesperson)","ru":"представитель родителей (в классе/школе)","vi":"đại diện phụ huynh","fa":"نماینده والدین","examples":[{"de":"Der Elternsprecher lädt zur nächsten Versammlung ein.","en":"The parents' representative invites everyone to the next meeting.","ru":"Представитель родителей приглашает всех на следующее собрание.","vi":"Đại diện phụ huynh mời bạn đến cuộc họp tiếp theo.","fa":"نماینده والدین شما را به جلسه بعدی دعوت می کند."},{"de":"Als Elternsprecher vertritt er die Interessen aller Eltern.","en":"As parents' representative he represents the interests of all parents.","ru":"Как представитель родителей он отстаивает интересы всех родителей.","vi":"Với tư cách là đại diện phụ huynh, ông đại diện cho quyền lợi của tất cả phụ huynh.","fa":"او به عنوان نماینده والدین، منافع همه والدین را نمایندگی می کند."},{"de":"Wir haben einen neuen Elternsprecher gewählt.","en":"We elected a new parents' representative.","ru":"Мы избрали нового представителя родителей.","vi":"Chúng tôi đã bầu ra một đại diện phụ huynh mới.","fa":"ما یک نماینده والدین جدید انتخاب کرده ایم."}]},{"word":"der Empfang","en":"reception; receipt; (signal) reception","ru":"приём; получение; (сигнала) приём","vi":"sự tiếp nhận","fa":"پذیرایی","examples":[{"de":"Bitte melden Sie sich am Empfang des Hotels.","en":"Please check in at the hotel reception.","ru":"Пожалуйста, зарегистрируйтесь на ресепшене отеля.","vi":"Vui lòng thông báo cho lễ tân khách sạn.","fa":"لطفا به پذیرش هتل گزارش دهید."},{"de":"Hier habe ich leider keinen Empfang mit dem Handy.","en":"Unfortunately I have no signal with my mobile here.","ru":"К сожалению, здесь у меня нет сигнала на телефоне.","vi":"Thật không may, tôi không có sóng điện thoại di động ở đây.","fa":"متاسفانه من اینجا گیرنده تلفن همراه ندارم."},{"de":"Nach der Hochzeit gab es einen feierlichen Empfang.","en":"After the wedding there was a formal reception.","ru":"После свадьбы был торжественный приём.","vi":"Sau đám cưới là tiệc chiêu đãi hoành tráng.","fa":"بعد از عروسی یک پذیرایی جشن برگزار شد."}]},{"word":"empfangen","en":"to receive (guests, a signal)","ru":"принимать (гостей, сигнал)","vi":"đã nhận được","fa":"دریافت کرد","examples":[{"de":"Wir wurden herzlich von der Familie empfangen.","en":"We were warmly received by the family.","ru":"Семья тепло приняла нас.","vi":"Chúng tôi được gia đình chào đón nồng nhiệt.","fa":"خانواده به گرمی از ما استقبال کردند."},{"de":"Hier kann man kein WLAN-Signal empfangen.","en":"You can't receive a Wi-Fi signal here.","ru":"Здесь нельзя принять сигнал Wi-Fi.","vi":"Bạn không thể nhận được tín hiệu WiFi ở đây.","fa":"در اینجا نمی توانید سیگنال WiFi دریافت کنید."}]},{"word":"empfehlen","en":"to recommend","ru":"рекомендовать","vi":"đề nghị","fa":"توصیه می کنند","examples":[{"de":"Kannst du mir ein gutes Restaurant empfehlen?","en":"Can you recommend a good restaurant to me?","ru":"Можешь порекомендовать мне хороший ресторан?","vi":"Bạn có thể giới thiệu cho tôi một nhà hàng tốt được không?","fa":"آیا می توانید یک رستوران خوب به من معرفی کنید؟"},{"de":"Der Arzt empfiehlt mehr Bewegung.","en":"The doctor recommends more exercise.","ru":"Врач рекомендует больше двигаться.","vi":"Bác sĩ khuyên nên tập thể dục nhiều hơn.","fa":"پزشک ورزش بیشتر را توصیه می کند."}]},{"word":"die Empfehlung","en":"recommendation","ru":"рекомендация","vi":"khuyến nghị","fa":"توصیه","examples":[{"de":"Auf Empfehlung eines Freundes habe ich das Buch gelesen.","en":"On a friend's recommendation I read the book.","ru":"По рекомендации друга я прочитал эту книгу.","vi":"Tôi đọc cuốn sách này theo lời giới thiệu của một người bạn.","fa":"من کتاب را به توصیه یکی از دوستان خواندم."},{"de":"Der Arzt gab mir eine klare Empfehlung.","en":"The doctor gave me a clear recommendation.","ru":"Врач дал мне чёткую рекомендацию.","vi":"Bác sĩ đã cho tôi một lời khuyên rõ ràng.","fa":"دکتر به من توصیه واضحی کرد."},{"de":"Diese Empfehlung kann ich nur weitergeben.","en":"I can only pass on this recommendation.","ru":"Могу только передать эту рекомендацию дальше.","vi":"Tôi chỉ có thể chuyển lời đề nghị này.","fa":"من فقط می توانم این توصیه را منتقل کنم."}]},{"word":"empfindlich","en":"sensitive","ru":"чувствительный; восприимчивый; (о холоде) ощутимый","vi":"nhạy cảm","fa":"حساس","examples":[{"de":"Meine Haut ist sehr empfindlich gegen Sonne.","en":"My skin is very sensitive to the sun.","ru":"Моя кожа очень чувствительна к солнцу.","vi":"Da của tôi rất nhạy cảm với ánh nắng mặt trời.","fa":"پوست من به آفتاب بسیار حساس است."},{"de":"Er reagiert empfindlich auf Kritik.","en":"He reacts sensitively to criticism.","ru":"Он болезненно реагирует на критику.","vi":"Anh ấy rất nhạy cảm với những lời chỉ trích.","fa":"او نسبت به انتقاد حساس است."},{"de":"Bei empfindlichem Wetter bleibe ich lieber zu Hause.","en":"In harsh weather I prefer to stay at home.","ru":"В непогоду я предпочитаю оставаться дома.","vi":"Khi thời tiết xấu, tôi thích ở nhà hơn.","fa":"وقتی هوا بد است ترجیح می دهم در خانه بمانم."}]},{"word":"enden","en":"to end","ru":"заканчиваться","vi":"kết thúc","fa":"پایان","examples":[{"de":"Der Film endet mit einem Happy End.","en":"The movie ends with a happy ending.","ru":"Фильм заканчивается счастливым концом.","vi":"Bộ phim kết thúc với một kết thúc có hậu.","fa":"فیلم با پایانی خوش به پایان می رسد."},{"de":"Wann endet der Kurs?","en":"When does the course end?","ru":"Когда заканчивается курс?","vi":"Khi nào khóa học kết thúc?","fa":"دوره چه زمانی تمام می شود؟"}]},{"word":"endgültig","en":"final, definitive","ru":"окончательный, бесповоротный","vi":"cuối cùng","fa":"نهایی","examples":[{"de":"Die Entscheidung ist jetzt endgültig.","en":"The decision is now final.","ru":"Решение теперь окончательное.","vi":"Quyết định bây giờ là cuối cùng.","fa":"اکنون تصمیم نهایی است."},{"de":"Hast du dich endgültig für diese Stelle entschieden?","en":"Have you definitively decided on this job?","ru":"Ты окончательно решился на эту работу?","vi":"Cuối cùng bạn đã quyết định vị trí này chưa?","fa":"بالاخره تصمیم گرفتی برای این سمت؟"},{"de":"Der Termin steht noch nicht endgültig fest.","en":"The date is not yet definitely fixed.","ru":"Дата пока окончательно не назначена.","vi":"Ngày vẫn chưa được quyết định.","fa":"تاریخ هنوز قطعی نشده است."}]},{"word":"endlich","en":"finally, at last","ru":"наконец","vi":"cuối cùng","fa":"در نهایت","examples":[{"de":"Endlich ist das Wochenende da!","en":"Finally the weekend is here!","ru":"Наконец-то настали выходные!","vi":"Cuối tuần cuối cùng cũng đã đến!","fa":"آخر هفته بالاخره رسید!"},{"de":"Nach langem Warten kam der Bus endlich.","en":"After a long wait, the bus finally came.","ru":"После долгого ожидания автобус наконец приехал.","vi":"Sau một hồi chờ đợi cuối cùng xe buýt cũng đến.","fa":"بعد از مدت ها انتظار بالاخره اتوبوس آمد."}]},{"word":"die Energie","en":"energy","ru":"энергия","vi":"năng lượng","fa":"انرژی","examples":[{"de":"Wir sollten Energie sparen.","en":"We should save energy.","ru":"Нам следует экономить энергию.","vi":"Chúng ta nên tiết kiệm năng lượng.","fa":"ما باید در مصرف انرژی صرفه جویی کنیم."},{"de":"Diese Fabrik produziert Energie aus Sonnenlicht.","en":"This factory produces energy from sunlight.","ru":"Эта фабрика производит энергию из солнечного света.","vi":"Nhà máy này sản xuất năng lượng từ ánh sáng mặt trời.","fa":"این کارخانه از نور خورشید انرژی تولید می کند."}]},{"word":"der Energieverbrauch","en":"energy consumption","ru":"потребление энергии, энергопотребление","vi":"tiêu thụ năng lượng","fa":"مصرف انرژی","examples":[{"de":"Der Energieverbrauch im Haushalt ist im Winter höher.","en":"Energy consumption in the household is higher in winter.","ru":"Потребление энергии в доме зимой выше.","vi":"Mức tiêu thụ năng lượng của hộ gia đình cao hơn vào mùa đông.","fa":"مصرف انرژی خانگی در زمستان بیشتر است."},{"de":"Neue Geräte senken oft den Energieverbrauch.","en":"New appliances often lower energy consumption.","ru":"Новые приборы часто снижают потребление энергии.","vi":"Các thiết bị mới thường giảm mức tiêu thụ năng lượng.","fa":"دستگاه های جدید اغلب مصرف انرژی را کاهش می دهند."},{"de":"Wir wollen unseren Energieverbrauch deutlich reduzieren.","en":"We want to reduce our energy consumption considerably.","ru":"Мы хотим значительно снизить наше потребление энергии.","vi":"Chúng tôi muốn giảm đáng kể mức tiêu thụ năng lượng của mình.","fa":"ما می خواهیم مصرف انرژی خود را به میزان قابل توجهی کاهش دهیم."}]},{"word":"eng","en":"narrow; tight","ru":"узкий; тесный","vi":"chặt chẽ","fa":"تنگ","examples":[{"de":"Die Straße in der Altstadt ist sehr eng.","en":"The street in the old town is very narrow.","ru":"Улица в старом городе очень узкая.","vi":"Đường phố trong phố cổ rất hẹp.","fa":"خیابان در شهر قدیمی بسیار باریک است."},{"de":"Diese Hose ist mir zu eng.","en":"These trousers are too tight for me.","ru":"Эти брюки мне слишком тесны.","vi":"Chiếc quần này quá chật đối với tôi.","fa":"این شلوار برای من خیلی تنگ است."}]},{"word":"der Enkel","en":"grandson","ru":"внук","vi":"cháu trai","fa":"نوه","examples":[{"de":"Mein Enkel besucht mich jeden Sommer.","en":"My grandson visits me every summer.","ru":"Мой внук навещает меня каждое лето.","vi":"Cháu trai tôi đến thăm tôi vào mỗi mùa hè.","fa":"نوه ام هر تابستان به دیدنم می آید."},{"de":"Die Großmutter spielt gerne mit ihrem Enkel.","en":"The grandmother likes to play with her grandson.","ru":"Бабушка любит играть со своим внуком.","vi":"Bà ngoại thích chơi với cháu trai.","fa":"مادربزرگ دوست دارد با نوه اش بازی کند."}]},{"word":"entdecken","en":"to discover","ru":"открывать, обнаруживать","vi":"khám phá","fa":"کشف کنید","examples":[{"de":"Kolumbus entdeckte Amerika im Jahr 1492.","en":"Columbus discovered America in 1492.","ru":"Колумб открыл Америку в 1492 году.","vi":"Columbus phát hiện ra châu Mỹ vào năm 1492.","fa":"کلمب آمریکا را در سال 1492 کشف کرد."},{"de":"Wir haben ein neues Café in der Stadt entdeckt.","en":"We discovered a new café in the city.","ru":"Мы обнаружили новое кафе в городе.","vi":"Chúng tôi phát hiện ra một quán cà phê mới trong thị trấn.","fa":"ما یک کافه جدید در شهر کشف کردیم."}]},{"word":"entfernen","en":"to remove","ru":"удалять, убирать","vi":"loại bỏ","fa":"حذف کنید","examples":[{"de":"Bitte entfernen Sie das Preisschild.","en":"Please remove the price tag.","ru":"Пожалуйста, удалите ценник.","vi":"Vui lòng xóa thẻ giá.","fa":"لطفا برچسب قیمت را بردارید"},{"de":"Der Fleck lässt sich nicht entfernen.","en":"The stain cannot be removed.","ru":"Пятно невозможно удалить.","vi":"Vết bẩn không thể được loại bỏ.","fa":"لکه را نمی توان پاک کرد."}]},{"word":"die Entfernung","en":"distance","ru":"расстояние, удалённость","vi":"khoảng cách","fa":"فاصله","examples":[{"de":"Die Entfernung zwischen den beiden Städten beträgt 100 Kilometer.","en":"The distance between the two cities is 100 kilometres.","ru":"Расстояние между двумя городами — 100 километров.","vi":"Khoảng cách giữa hai thành phố là 100 km.","fa":"فاصله این دو شهر 100 کیلومتر است."},{"de":"Aus dieser Entfernung kann ich das Schild nicht lesen.","en":"From this distance I can't read the sign.","ru":"С такого расстояния я не могу прочитать знак.","vi":"Tôi không thể đọc được biển báo từ khoảng cách này.","fa":"من نمی توانم علامت را از این فاصله بخوانم."},{"de":"Die Entfernung zur Arbeit ist mir zu groß.","en":"The distance to work is too great for me.","ru":"Расстояние до работы для меня слишком велико.","vi":"Khoảng cách đến nơi làm việc là quá lớn đối với tôi.","fa":"فاصله تا محل کار برای من خیلی زیاد است."}]},{"word":"entgegenkommen","en":"to accommodate (someone), meet halfway","ru":"идти навстречу, уступать","vi":"chứa đựng","fa":"جای دادن","examples":[{"de":"Der Verkäufer ist uns beim Preis entgegengekommen.","en":"The seller met us halfway on the price.","ru":"Продавец пошёл нам навстречу в цене.","vi":"Người bán đã hỗ trợ chúng tôi về giá cả.","fa":"فروشنده ما را در قیمت جا داد."},{"de":"Mein Chef kommt mir bei den Arbeitszeiten entgegen.","en":"My boss accommodates me regarding working hours.","ru":"Мой начальник идёт мне навстречу по рабочему времени.","vi":"Sếp của tôi giúp đỡ tôi về giờ làm việc.","fa":"در مورد ساعات کار، رئیس من از من استقبال می کند."}]},{"word":"enthalten","en":"to contain","ru":"содержать","vi":"bao gồm","fa":"گنجانده شده است","examples":[{"de":"Diese Suppe enthält viel Salz.","en":"This soup contains a lot of salt.","ru":"Этот суп содержит много соли.","vi":"Món súp này chứa rất nhiều muối.","fa":"این سوپ حاوی مقدار زیادی نمک است."},{"de":"Der Preis enthält bereits die Mehrwertsteuer.","en":"The price already includes VAT.","ru":"Цена уже включает НДС.","vi":"Giá đã bao gồm VAT rồi.","fa":"قیمت از قبل شامل مالیات بر ارزش افزوده است."}]},{"word":"entlang","en":"along","ru":"вдоль","vi":"dọc theo","fa":"همراه","examples":[{"de":"Wir gehen den Fluss entlang.","en":"We are walking along the river.","ru":"Мы идём вдоль реки.","vi":"Chúng tôi đi dọc bờ sông.","fa":"در کنار رودخانه قدم می زنیم."},{"de":"Entlang der Straße stehen viele Bäume.","en":"Many trees stand along the street.","ru":"Вдоль улицы стоит много деревьев.","vi":"Có rất nhiều cây dọc theo con đường.","fa":"درختان زیادی در کنار جاده وجود دارد."}]},{"word":"entlassen","en":"to dismiss/lay off (from a job); to discharge","ru":"увольнять; выписывать (из больницы)","vi":"bị sa thải","fa":"اخراج شد","examples":[{"de":"Die Firma musste viele Mitarbeiter entlassen.","en":"The company had to lay off many employees.","ru":"Компании пришлось уволить многих сотрудников.","vi":"Công ty đã phải sa thải nhiều nhân viên.","fa":"شرکت مجبور شد بسیاری از کارمندان را اخراج کند."},{"de":"Der Patient wurde gestern aus dem Krankenhaus entlassen.","en":"The patient was discharged from the hospital yesterday.","ru":"Пациента вчера выписали из больницы.","vi":"Bệnh nhân đã được xuất viện ngày hôm qua.","fa":"بیمار دیروز از بیمارستان مرخص شد."}]},{"word":"entscheiden","en":"to decide","ru":"решать","vi":"quyết định","fa":"تصمیم بگیرند","examples":[{"de":"Ich kann mich nicht entscheiden, welches Kleid ich kaufen soll.","en":"I can't decide which dress to buy.","ru":"Я не могу решить, какое платье купить.","vi":"Tôi không thể quyết định nên mua chiếc váy nào.","fa":"من نمی توانم تصمیم بگیرم کدام لباس را بخرم."},{"de":"Wir müssen bald entscheiden, wohin wir in Urlaub fahren.","en":"We need to decide soon where we're going on vacation.","ru":"Нам нужно скоро решить, куда поехать в отпуск.","vi":"Chúng ta phải quyết định sớm nơi chúng ta sẽ đi nghỉ.","fa":"ما باید به زودی تصمیم بگیریم که به تعطیلات کجا برویم."}]},{"word":"die Entscheidung","en":"decision","ru":"решение","vi":"quyết định","fa":"تصمیم","examples":[{"de":"Das war die schwierigste Entscheidung meines Lebens.","en":"That was the most difficult decision of my life.","ru":"Это было самое трудное решение в моей жизни.","vi":"Đó là quyết định khó khăn nhất trong cuộc đời tôi.","fa":"این سخت ترین تصمیم زندگی من بود."},{"de":"Wir müssen bis morgen eine Entscheidung treffen.","en":"We have to make a decision by tomorrow.","ru":"Мы должны принять решение до завтра.","vi":"Chúng ta phải đưa ra quyết định vào ngày mai.","fa":"تا فردا باید تصمیم بگیریم."}]},{"word":"die Entscheidung treffen","en":"to make a decision","ru":"принимать решение","vi":"đưa ra quyết định","fa":"تصمیم بگیر","examples":[{"de":"Du musst selbst eine Entscheidung treffen.","en":"You have to make a decision yourself.","ru":"Ты должен сам принять решение.","vi":"Bạn phải tự mình đưa ra quyết định.","fa":"خودت باید تصمیم بگیری"},{"de":"Sie traf die Entscheidung sehr schnell.","en":"She made the decision very quickly.","ru":"Она приняла решение очень быстро.","vi":"Cô ấy đưa ra quyết định rất nhanh chóng.","fa":"او خیلی سریع تصمیم گرفت."},{"de":"Wir konnten keine Entscheidung treffen.","en":"We could not make a decision.","ru":"Мы не смогли принять решение.","vi":"Chúng tôi không thể đưa ra quyết định.","fa":"ما نتوانستیم تصمیمی بگیریم."}]},{"word":"entschließen","en":"to resolve, make up one's mind (reflexive: sich entschließen)","ru":"решаться, принимать решение (возвратный: sich entschließen)","vi":"quyết định","fa":"تصمیم بگیرند","examples":[{"de":"Endlich hat er sich entschlossen, das Studium zu beginnen.","en":"He has finally made up his mind to start his studies.","ru":"Он наконец решился начать учёбу.","vi":"Cuối cùng anh quyết định bắt đầu học.","fa":"بالاخره تصمیم گرفت درس بخواند."},{"de":"Wir konnten uns lange nicht entschließen.","en":"For a long time we couldn't make up our minds.","ru":"Мы долго не могли решиться.","vi":"Chúng tôi không thể quyết định trong một thời gian dài.","fa":"خیلی وقت بود که نمی توانستیم تصمیم بگیریم."},{"de":"Sie entschloss sich, das Angebot anzunehmen.","en":"She resolved to accept the offer.","ru":"Она решилась принять предложение.","vi":"Cô quyết định chấp nhận lời đề nghị.","fa":"او تصمیم گرفت این پیشنهاد را بپذیرد."}]},{"word":"entschuldigen","en":"to excuse; sich entschuldigen: to apologize","ru":"извинять(ся)","vi":"xin lỗi","fa":"عذرخواهی کن","examples":[{"de":"Entschuldigen Sie bitte die Verspätung.","en":"Please excuse the delay.","ru":"Извините, пожалуйста, за опоздание.","vi":"Xin thứ lỗi cho sự chậm trễ.","fa":"لطفا تاخیر را ببخشید"},{"de":"Er hat sich für seinen Fehler entschuldigt.","en":"He apologized for his mistake.","ru":"Он извинился за свою ошибку.","vi":"Anh xin lỗi vì sai lầm của mình.","fa":"از اشتباهش عذرخواهی کرد."}]},{"word":"die Entschuldigung","en":"apology; excuse","ru":"извинение; оправдание","vi":"lời xin lỗi","fa":"عذرخواهی","examples":[{"de":"Er hat sich mit einer Entschuldigung bei mir gemeldet.","en":"He contacted me with an apology.","ru":"Он связался со мной с извинением.","vi":"Anh ấy đã liên lạc với tôi để xin lỗi.","fa":"او با من تماس گرفت و عذرخواهی کرد."},{"de":"Entschuldigung, wissen Sie, wo der Bahnhof ist?","en":"Excuse me, do you know where the train station is?","ru":"Извините, вы не знаете, где вокзал?","vi":"Xin lỗi, bạn có biết ga xe lửa ở đâu không?","fa":"ببخشید میدونید ایستگاه قطار کجاست؟"}]},{"word":"Entschuldigung, das habe ich nicht verstanden","en":"Sorry, I didn't understand that (signalling non-understanding)","ru":"Извините, я не понял (сигнал непонимания)","vi":"Xin lỗi, tôi không hiểu điều đó","fa":"ببخشید من متوجه نشدم","examples":[{"de":"Entschuldigung, das habe ich nicht verstanden. Bitte langsamer.","en":"Sorry, I didn't understand that. Slower, please.","ru":"Извините, я не понял. Пожалуйста, помедленнее.","vi":"Xin lỗi, tôi không hiểu điều đó. Xin hãy chậm lại.","fa":"ببخشید من متوجه نشدم لطفا سرعت خود را کم کنید."}]},{"word":"entsorgen","en":"to dispose of","ru":"утилизировать, избавляться от","vi":"vứt bỏ","fa":"دور انداختن","examples":[{"de":"Alte Batterien muss man richtig entsorgen.","en":"Old batteries must be disposed of properly.","ru":"Старые батарейки нужно правильно утилизировать.","vi":"Pin cũ phải được xử lý đúng cách.","fa":"باتری های قدیمی باید به درستی دور ریخته شوند."},{"de":"Wir entsorgen den Müll getrennt nach Papier und Plastik.","en":"We dispose of the waste separately by paper and plastic.","ru":"Мы утилизируем мусор раздельно по бумаге и пластику.","vi":"Chúng tôi xử lý rác thải riêng biệt thành giấy và nhựa.","fa":"زباله ها را به طور جداگانه در کاغذ و پلاستیک دفع می کنیم."}]},{"word":"entspannend","en":"relaxing","ru":"расслабляющий","vi":"thư giãn","fa":"آرامش بخش","examples":[{"de":"Ein Spaziergang im Wald ist sehr entspannend.","en":"A walk in the forest is very relaxing.","ru":"Прогулка в лесу очень расслабляет.","vi":"Đi dạo trong rừng rất thư giãn.","fa":"قدم زدن در جنگل بسیار آرامش بخش است."},{"de":"Nach der Arbeit finde ich Musik entspannend.","en":"After work I find music relaxing.","ru":"После работы музыка меня расслабляет.","vi":"Tôi thấy âm nhạc thư giãn sau giờ làm việc.","fa":"به نظرم موسیقی بعد از کار آرامش بخش است."}]},{"word":"die Entspannung","en":"relaxation","ru":"расслабление; разрядка (напряжения)","vi":"sự thư giãn","fa":"آرامش","examples":[{"de":"Am Ende der Yogastunde folgt eine tiefe Entspannung im Liegen.","en":"At the end of the yoga class comes a deep relaxation lying down.","ru":"В конце занятия йогой следует глубокое расслабление лёжа.","vi":"Vào cuối lớp học yoga, bạn sẽ có cảm giác thư giãn sâu khi nằm.","fa":"در پایان کلاس یوگا یک آرامش عمیق در حالت دراز کشیدن وجود دارد."},{"de":"Ein warmes Bad am Abend sorgt bei mir für Entspannung.","en":"A warm bath in the evening brings me relaxation.","ru":"Тёплая ванна вечером помогает мне расслабиться.","vi":"Tắm nước ấm vào buổi tối giúp tôi thư giãn.","fa":"حمام آب گرم در عصر به من آرامش می دهد."},{"de":"Nach der stressigen Woche suchte er Ruhe und Entspannung am Meer.","en":"After the stressful week he sought peace and relaxation by the sea.","ru":"После напряжённой недели он искал покоя и отдыха у моря.","vi":"Sau một tuần căng thẳng, anh tìm đến sự bình yên, thư thái bên bờ biển.","fa":"او پس از هفته پر استرس به دنبال آرامش و آرامش در کنار دریا بود."}]},{"word":"die Entspannungsübung","en":"relaxation exercise","ru":"упражнение на расслабление, релаксационное упражнение","vi":"bài tập thư giãn","fa":"تمرین تمدد اعصاب","examples":[{"de":"Vor dem Schlafen mache ich eine kurze Entspannungsübung.","en":"Before sleeping I do a short relaxation exercise.","ru":"Перед сном я делаю короткое упражнение на расслабление.","vi":"Trước khi đi ngủ, tôi tập một bài tập thư giãn ngắn.","fa":"قبل از اینکه بخوابم یک تمرین آرام سازی کوتاه انجام می دهم."},{"de":"Die Entspannungsübung hilft gegen Stress.","en":"The relaxation exercise helps against stress.","ru":"Упражнение на расслабление помогает от стресса.","vi":"Bài tập thư giãn giúp chống lại căng thẳng.","fa":"ورزش آرام سازی به مقابله با استرس کمک می کند."},{"de":"Der Kurs beginnt immer mit einer Entspannungsübung.","en":"The class always begins with a relaxation exercise.","ru":"Занятие всегда начинается с упражнения на расслабление.","vi":"Khóa học luôn bắt đầu bằng một bài tập thư giãn.","fa":"این دوره همیشه با یک تمرین آرام سازی شروع می شود."}]},{"word":"entstehen","en":"to arise, come into being","ru":"возникать","vi":"phát sinh","fa":"بوجود می آیند","examples":[{"de":"Durch den Unfall entstand ein großer Stau.","en":"The accident caused a big traffic jam.","ru":"Из-за аварии возникла большая пробка.","vi":"Vụ tai nạn khiến giao thông ùn tắc lớn.","fa":"این تصادف باعث ایجاد ترافیک بزرگ شد."},{"de":"Hier soll bald ein neues Einkaufszentrum entstehen.","en":"A new shopping center is supposed to be built here soon.","ru":"Здесь скоро должен появиться новый торговый центр.","vi":"Một trung tâm mua sắm mới sẽ sớm được xây dựng ở đây.","fa":"به زودی یک مرکز خرید جدید در اینجا ساخته خواهد شد."}]},{"word":"enttäuschen","en":"to disappoint","ru":"разочаровывать","vi":"thất vọng","fa":"ناامید کردن","examples":[{"de":"Das Ergebnis hat mich sehr enttäuscht.","en":"The result disappointed me a lot.","ru":"Результат меня сильно разочаровал.","vi":"Kết quả thực sự làm tôi thất vọng.","fa":"نتیجه واقعاً من را ناامید کرد."},{"de":"Ich möchte meine Eltern nicht enttäuschen.","en":"I don't want to disappoint my parents.","ru":"Я не хочу разочаровывать своих родителей.","vi":"Tôi không muốn làm bố mẹ thất vọng.","fa":"من نمی خواهم پدر و مادرم را ناامید کنم."}]},{"word":"enttäuscht","en":"disappointed","ru":"разочарованный","vi":"thất vọng","fa":"ناامید شده","examples":[{"de":"Ich bin enttäuscht, das hören zu müssen.","en":"I'm disappointed to hear that.","ru":"Я разочарован, что вынужден это слышать.","vi":"Tôi thất vọng khi nghe điều này.","fa":"من از شنیدن این موضوع ناامید شدم."},{"de":"Die Fans waren vom Ergebnis tief enttäuscht.","en":"The fans were deeply disappointed by the result.","ru":"Болельщики были глубоко разочарованы результатом.","vi":"Người hâm mộ vô cùng thất vọng với kết quả này.","fa":"هواداران به شدت از این نتیجه ناامید شدند."},{"de":"Ich bin enttäuscht von dir.","en":"I'm disappointed in you.","ru":"Я в тебе разочарован.","vi":"Tôi thất vọng về bạn.","fa":"من از شما ناامیدم"}]},{"word":"die Enttäuschung","en":"disappointment","ru":"разочарование","vi":"sự thất vọng","fa":"ناامیدی","examples":[{"de":"Die Niederlage war eine große Enttäuschung.","en":"The defeat was a big disappointment.","ru":"Поражение было большим разочарованием.","vi":"Trận thua là một nỗi thất vọng lớn.","fa":"شکست یک ناامیدی بزرگ بود."},{"de":"Zu meiner Enttäuschung war das Geschäft schon zu.","en":"To my disappointment the shop was already closed.","ru":"К моему разочарованию, магазин уже был закрыт.","vi":"Trước sự thất vọng của tôi, cửa hàng đã đóng cửa.","fa":"با ناامیدی من، فروشگاه قبلاً بسته بود."}]},{"word":"entweder","en":"either (first part of the two-part conjunction entweder…oder…, presenting two alternatives)","ru":"либо (первая часть конструкции entweder…oder…, вводит две альтернативы)","vi":"hoặc là","fa":"یا","examples":[{"de":"Entweder machen wir das gemeinsam, oder ich mache es alleine.","en":"Either we do this together, or I do it on my own.","ru":"Либо мы делаем это вместе, либо я делаю это сам.","vi":"Hoặc là chúng ta làm việc đó cùng nhau hoặc tôi làm việc đó một mình.","fa":"یا با هم انجامش می دهیم یا من به تنهایی."},{"de":"Entweder du hilfst mir jetzt, oder ich rufe jemand anderen an.","en":"Either you help me now, or I will ring someone else.","ru":"Либо ты сейчас поможешь мне, либо я позвоню кому-нибудь другому.","vi":"Hoặc là bạn giúp tôi ngay bây giờ hoặc tôi sẽ gọi người khác.","fa":"یا الان کمکم کن یا با یکی دیگه تماس میگیرم."},{"de":"Wir fahren entweder mit dem Zug oder mit dem Auto.","en":"We are travelling either by train or by car.","ru":"Мы едем либо на поезде, либо на машине.","vi":"Chúng tôi đi bằng tàu hỏa hoặc ô tô.","fa":"یا با قطار می رویم یا با ماشین."}]},{"word":"entweder ... oder","en":"either ... or","ru":"либо ... либо","vi":"hoặc...hoặc","fa":"یا...یا","examples":[{"de":"Wir können entweder ins Kino oder ins Theater gehen.","en":"We can go either to the cinema or to the theater.","ru":"Мы можем пойти либо в кино, либо в театр.","vi":"Chúng ta có thể đi xem phim hoặc đi xem kịch.","fa":"یا می توانیم سینما برویم یا تئاتر."},{"de":"Entweder du lernst jetzt, oder du fällst durch die Prüfung.","en":"Either you study now, or you'll fail the exam.","ru":"Либо ты учишься сейчас, либо провалишь экзамен.","vi":"Hoặc là bạn học bây giờ hoặc bạn trượt kỳ thi.","fa":"یا الان درس می خوانی یا در امتحان مردود می شوی."}]},{"word":"entwickeln","en":"to develop","ru":"развивать(ся)","vi":"phát triển","fa":"توسعه دهد","examples":[{"de":"Die Firma entwickelt eine neue App.","en":"The company is developing a new app.","ru":"Компания разрабатывает новое приложение.","vi":"Công ty đang phát triển một ứng dụng mới.","fa":"این شرکت در حال توسعه یک برنامه جدید است."},{"de":"Er hat sich in den letzten Jahren sehr entwickelt.","en":"He has developed a lot in recent years.","ru":"За последние годы он сильно изменился.","vi":"Anh ấy đã phát triển rất nhiều trong vài năm qua.","fa":"او در چند سال اخیر پیشرفت زیادی کرده است."}]},{"word":"die Entwickelung","en":"development (older/variant spelling of Entwicklung)","ru":"развитие (устаревшее/вариантное написание Entwicklung)","vi":"sự phát triển","fa":"توسعه","examples":[{"de":"Die Entwickelung dieser Idee dauerte mehrere Jahre.","en":"The development of this idea took several years.","ru":"Развитие этой идеи заняло несколько лет.","vi":"Sự phát triển của ý tưởng này mất vài năm.","fa":"توسعه این ایده چندین سال طول کشید."},{"de":"In alten Texten findet man oft die Schreibweise Entwickelung.","en":"In old texts you often find the spelling Entwickelung.","ru":"В старых текстах часто встречается написание Entwickelung.","vi":"Sự phát triển chính tả thường được tìm thấy trong các văn bản cũ.","fa":"توسعه املایی اغلب در متون قدیمی یافت می شود."},{"de":"Die Entwickelung des Kindes verlief völlig normal.","en":"The development of the child proceeded entirely normally.","ru":"Развитие ребёнка шло совершенно нормально.","vi":"Sự phát triển của trẻ hoàn toàn bình thường.","fa":"رشد کودک کاملا طبیعی بود."}]},{"word":"der Entwickler","en":"developer","ru":"разработчик","vi":"nhà phát triển","fa":"توسعه دهنده","examples":[{"de":"Der Entwickler arbeitet an einer neuen Version der App.","en":"The developer is working on a new version of the app.","ru":"Разработчик работает над новой версией приложения.","vi":"Nhà phát triển đang làm việc trên một phiên bản mới của ứng dụng.","fa":"توسعه دهنده در حال کار بر روی نسخه جدیدی از برنامه است."},{"de":"Melde den Fehler bitte direkt dem Entwickler.","en":"Please report the bug directly to the developer.","ru":"Пожалуйста, сообщи об ошибке прямо разработчику.","vi":"Vui lòng báo cáo lỗi trực tiếp cho nhà phát triển.","fa":"لطفاً خطا را مستقیماً به توسعه دهنده گزارش دهید."},{"de":"Als Entwickler schreibt sie den ganzen Tag Code.","en":"As a developer she writes code all day long.","ru":"Как разработчик она весь день пишет код.","vi":"Là một nhà phát triển, cô ấy viết mã cả ngày.","fa":"به عنوان یک توسعه دهنده، او تمام روز کد می نویسد."}]},{"word":"die Entwicklung","en":"development","ru":"развитие","vi":"sự phát triển","fa":"توسعه","examples":[{"de":"Die technische Entwicklung schreitet immer schneller voran.","en":"Technical development is advancing ever faster.","ru":"Технологическое развитие идёт всё быстрее.","vi":"Sự phát triển kỹ thuật đang tiến triển nhanh hơn bao giờ hết.","fa":"توسعه فنی با سرعت بیشتری در حال پیشرفت است."},{"de":"Die Eltern beobachten die Entwicklung ihres Kindes genau.","en":"The parents closely observe their child's development.","ru":"Родители внимательно следят за развитием своего ребёнка.","vi":"Cha mẹ theo dõi chặt chẽ sự phát triển của con mình.","fa":"والدین به دقت رشد کودک خود را زیر نظر دارند."}]},{"word":"die Epoche","en":"era, epoch","ru":"эпоха","vi":"thời đại","fa":"دوران","examples":[{"de":"Diese Epoche war von großen Veränderungen geprägt.","en":"This era was marked by great changes.","ru":"Эта эпоха была отмечена большими переменами.","vi":"Thời đại này được đánh dấu bằng những thay đổi lớn.","fa":"این دوره با تغییرات عمده ای همراه بود."},{"de":"Historiker teilen die Vergangenheit in verschiedene Epochen ein.","en":"Historians divide the past into different epochs.","ru":"Историки делят прошлое на разные эпохи.","vi":"Các nhà sử học chia quá khứ thành nhiều thời đại khác nhau.","fa":"مورخان گذشته را به دوره های مختلف تقسیم می کنند."},{"de":"Mit dem Mauerfall begann eine neue Epoche.","en":"A new era began with the fall of the Wall.","ru":"С падением Стены началась новая эпоха.","vi":"Với sự sụp đổ của Bức tường Berlin, một kỷ nguyên mới bắt đầu.","fa":"با فروریختن دیوار برلین، دوران جدیدی آغاز شد."}]},{"word":"er","en":"he, it","ru":"он, оно","vi":"anh ấy","fa":"او","examples":[{"de":"Er kommt heute später nach Hause.","en":"He's coming home later today.","ru":"Он сегодня придёт домой позже.","vi":"Anh ấy sẽ về nhà sau ngày hôm nay.","fa":"او امروز بعداً به خانه خواهد آمد."},{"de":"Mein Bruder ist Arzt; er arbeitet im Krankenhaus.","en":"My brother is a doctor; he works at the hospital.","ru":"Мой брат — врач, он работает в больнице.","vi":"Anh trai tôi là bác sĩ; anh ấy làm việc ở bệnh viện","fa":"برادر من پزشک است. او در بیمارستان کار می کند"},{"de":"Wo ist der Schlüssel? Er liegt auf dem Tisch.","en":"Where is the key? It's on the table.","ru":"Где ключ? Он на столе.","vi":"Chìa khóa ở đâu? Anh ấy đang nằm trên bàn.","fa":"کلید کجاست؟ او روی میز دراز کشیده است."}]},{"word":"der Erdapfel","en":"potato (Austrian/southern German for Kartoffel)","ru":"картошка (австрийское/южнонемецкое для Kartoffel)","vi":"khoai tây","fa":"سیب زمینی","examples":[{"de":"In Österreich sagt man Erdapfel statt Kartoffel.","en":"In Austria people say Erdapfel instead of Kartoffel.","ru":"В Австрии говорят Erdapfel вместо Kartoffel.","vi":"Ở Áo họ nói Erdapfel thay vì khoai tây.","fa":"در اتریش به جای سیب زمینی ارداپفل می گویند."},{"de":"Sie kochte die Erdäpfel für den Salat.","en":"She boiled the potatoes for the salad.","ru":"Она сварила картошку для салата.","vi":"Cô ấy nấu khoai tây cho món salad.","fa":"سیب زمینی را برای سالاد پخت."},{"de":"Frische Erdäpfel schmecken besonders gut mit Butter.","en":"Fresh potatoes taste especially good with butter.","ru":"Свежая картошка особенно вкусна с маслом.","vi":"Khoai tây tươi có vị đặc biệt ngon với bơ.","fa":"طعم سیب زمینی تازه به خصوص با کره خوب است."}]},{"word":"das Erdbeben","en":"earthquake","ru":"землетрясение","vi":"trận động đất","fa":"زلزله","examples":[{"de":"Das Erdbeben hat viele Häuser zerstört.","en":"The earthquake destroyed many houses.","ru":"Землетрясение разрушило много домов.","vi":"Trận động đất đã phá hủy nhiều ngôi nhà.","fa":"زلزله خانه های زیادی را ویران کرد."},{"de":"Bei dem Erdbeben gab es zum Glück keine Verletzten.","en":"Fortunately there were no injuries in the earthquake.","ru":"При землетрясении, к счастью, никто не пострадал.","vi":"Rất may không có thương vong trong trận động đất.","fa":"خوشبختانه این زلزله خسارت جانی نداشت."},{"de":"In dieser Region gibt es häufig kleine Erdbeben.","en":"In this region there are frequently small earthquakes.","ru":"В этом регионе часто бывают небольшие землетрясения.","vi":"Các trận động đất nhỏ thường xuyên xảy ra ở khu vực này.","fa":"زلزله های کوچک اغلب در این منطقه رخ می دهد."}]},{"word":"die Erde","en":"earth; soil","ru":"земля; почва","vi":"trái đất","fa":"زمین","examples":[{"de":"Die Erde dreht sich um die Sonne.","en":"The Earth revolves around the sun.","ru":"Земля вращается вокруг Солнца.","vi":"Trái đất quay quanh mặt trời.","fa":"زمین به دور خورشید می چرخد."},{"de":"Die Pflanze braucht gute Erde zum Wachsen.","en":"The plant needs good soil to grow.","ru":"Растению нужна хорошая почва, чтобы расти.","vi":"Cây cần đất tốt để phát triển.","fa":"این گیاه برای رشد به خاک مناسب نیاز دارد."}]},{"word":"die Erdölförderung","en":"oil extraction, oil production","ru":"добыча нефти","vi":"sản xuất dầu","fa":"تولید نفت","examples":[{"de":"Die Erdölförderung schadet oft der Umwelt.","en":"Oil extraction often harms the environment.","ru":"Добыча нефти часто вредит окружающей среде.","vi":"Sản xuất dầu thường gây hại cho môi trường.","fa":"تولید نفت اغلب به محیط زیست آسیب می رساند."},{"de":"In der Arktis ist die Erdölförderung besonders umstritten.","en":"In the Arctic, oil extraction is particularly controversial.","ru":"В Арктике добыча нефти особенно спорна.","vi":"Sản xuất dầu đặc biệt gây tranh cãi ở Bắc Cực.","fa":"تولید نفت به ویژه در قطب شمال بحث برانگیز است."},{"de":"Die Erdölförderung soll in den nächsten Jahren sinken.","en":"Oil production is expected to decline in the coming years.","ru":"Добыча нефти в ближайшие годы должна снизиться.","vi":"Sản lượng dầu dự kiến ​​sẽ giảm trong vài năm tới.","fa":"انتظار می رود تولید نفت در چند سال آینده کاهش یابد."}]},{"word":"das Ereignis","en":"event","ru":"событие","vi":"sự kiện","fa":"رویداد","examples":[{"de":"Die Hochzeit war ein wichtiges Ereignis für die Familie.","en":"The wedding was an important event for the family.","ru":"Свадьба была важным событием для семьи.","vi":"Đám cưới là một sự kiện quan trọng đối với gia đình.","fa":"عروسی یک رویداد مهم برای خانواده بود."},{"de":"In den Nachrichten wurde über das Ereignis berichtet.","en":"The news reported on the event.","ru":"В новостях сообщили об этом событии.","vi":"Sự kiện này đã được đưa tin trên bản tin.","fa":"این رویداد در اخبار منتشر شد."}]},{"word":"erfahren","en":"to find out, learn; (adj.) experienced","ru":"узнавать; (прил.) опытный","vi":"có kinh nghiệm","fa":"با تجربه","examples":[{"de":"Ich habe erst gestern von der Neuigkeit erfahren.","en":"I only found out about the news yesterday.","ru":"Я узнал об этой новости только вчера.","vi":"Tôi mới biết tin ngày hôm qua.","fa":"من تازه دیروز با خبر شدم."},{"de":"Sie ist eine sehr erfahrene Lehrerin.","en":"She is a very experienced teacher.","ru":"Она очень опытная учительница.","vi":"Cô ấy là một giáo viên rất giàu kinh nghiệm.","fa":"او یک معلم بسیار با تجربه است."}]},{"word":"die Erfahrung","en":"experience","ru":"опыт","vi":"trải nghiệm","fa":"تجربه","examples":[{"de":"Für diese Stelle braucht man mehrere Jahre Erfahrung.","en":"For this position you need several years of experience.","ru":"Для этой должности нужно несколько лет опыта.","vi":"Vị trí này yêu cầu nhiều năm kinh nghiệm.","fa":"این موقعیت مستلزم چندین سال تجربه است."},{"de":"Aus eigener Erfahrung weiß ich, wie schwer das ist.","en":"From my own experience I know how hard that is.","ru":"По собственному опыту я знаю, как это трудно.","vi":"Tôi biết từ kinh nghiệm của bản thân việc này khó khăn như thế nào.","fa":"من از تجربه خودم می دانم که این چقدر دشوار است."}]},{"word":"erfassen","en":"to record, to capture (data)","ru":"фиксировать, регистрировать (данные)","vi":"bắt giữ","fa":"گرفتن","examples":[{"de":"Wir erfassen alle Bestellungen im System.","en":"We record all orders in the system.","ru":"Мы фиксируем все заказы в системе.","vi":"Chúng tôi ghi lại tất cả các đơn đặt hàng trong hệ thống.","fa":"ما تمام سفارشات را در سیستم ثبت می کنیم."},{"de":"Die App erfasst automatisch deinen Standort.","en":"The app automatically captures your location.","ru":"Приложение автоматически фиксирует твоё местоположение.","vi":"Ứng dụng sẽ tự động ghi lại vị trí của bạn.","fa":"برنامه به طور خودکار موقعیت مکانی شما را ثبت می کند."},{"de":"Bitte erfasse die neuen Kundendaten sorgfältig.","en":"Please record the new customer data carefully.","ru":"Пожалуйста, тщательно зафиксируй данные нового клиента.","vi":"Vui lòng nhập dữ liệu khách hàng mới một cách cẩn thận.","fa":"لطفا اطلاعات مشتری جدید را با دقت وارد کنید."}]},{"word":"erfinden","en":"to invent","ru":"изобретать","vi":"phát minh","fa":"اختراع کردن","examples":[{"de":"Wer hat das Telefon erfunden?","en":"Who invented the telephone?","ru":"Кто изобрёл телефон?","vi":"Ai đã phát minh ra điện thoại?","fa":"چه کسی تلفن را اختراع کرد؟"},{"de":"Er erfindet gern Geschichten für seine Kinder.","en":"He likes inventing stories for his children.","ru":"Он любит придумывать истории для своих детей.","vi":"Anh ấy thích bịa ra những câu chuyện cho con mình.","fa":"او دوست دارد برای فرزندانش داستان بسازد."}]},{"word":"die Erfindung","en":"invention","ru":"изобретение","vi":"phát minh","fa":"اختراع","examples":[{"de":"Das Internet ist eine wichtige Erfindung.","en":"The internet is an important invention.","ru":"Интернет — важное изобретение.","vi":"Internet là một phát minh quan trọng.","fa":"اینترنت یک اختراع مهم است."},{"de":"Die Erfindung des Rades veränderte die Welt.","en":"The invention of the wheel changed the world.","ru":"Изобретение колеса изменило мир.","vi":"Việc phát minh ra bánh xe đã thay đổi thế giới.","fa":"اختراع چرخ دنیا را تغییر داد."}]},{"word":"der Erfolg","en":"success","ru":"успех","vi":"sự thành công","fa":"موفقیت","examples":[{"de":"Ich wünsche dir viel Erfolg bei der Prüfung.","en":"I wish you great success in the exam.","ru":"Желаю тебе большого успеха на экзамене.","vi":"Tôi chúc bạn thành công trong kỳ thi.","fa":"برای شما در امتحان آرزوی موفقیت دارم."},{"de":"Das neue Produkt war ein großer Erfolg.","en":"The new product was a great success.","ru":"Новый продукт имел большой успех.","vi":"Sản phẩm mới đã thành công rực rỡ.","fa":"محصول جدید یک موفقیت بزرگ بود."}]},{"word":"erfolglos","en":"unsuccessful","ru":"безуспешный, безрезультатный","vi":"không thành công","fa":"ناموفق","examples":[{"de":"Alle Versuche, ihn zu erreichen, blieben erfolglos.","en":"All attempts to reach him were unsuccessful.","ru":"Все попытки связаться с ним были безуспешны.","vi":"Mọi nỗ lực tiếp cận anh đều không thành công.","fa":"همه تلاش ها برای رسیدن به او ناموفق بود."},{"de":"Die Verhandlungen waren leider erfolglos.","en":"The negotiations were unfortunately unsuccessful.","ru":"Переговоры, к сожалению, оказались безрезультатными.","vi":"Thật không may, cuộc đàm phán đã không thành công.","fa":"متأسفانه مذاکرات ناموفق بود."},{"de":"Nach einer erfolglosen Suche gab sie auf.","en":"After an unsuccessful search she gave up.","ru":"После безуспешных поисков она сдалась.","vi":"Sau khi tìm kiếm không thành công, cô đã bỏ cuộc.","fa":"پس از جستجوی ناموفق، او منصرف شد."}]},{"word":"erfolgreich","en":"successful","ru":"успешный","vi":"thành công","fa":"موفق","examples":[{"de":"Die Firma ist in den letzten Jahren sehr erfolgreich.","en":"The company has been very successful in recent years.","ru":"Компания очень успешна в последние годы.","vi":"Công ty đã rất thành công trong những năm gần đây.","fa":"این شرکت در سال های اخیر بسیار موفق بوده است."},{"de":"Der Versuch war erfolgreich.","en":"The attempt was successful.","ru":"Попытка была успешной.","vi":"Nỗ lực đã thành công.","fa":"تلاش موفقیت آمیز بود."}]},{"word":"erforderlich","en":"required, necessary","ru":"необходимый, требуемый","vi":"bắt buộc","fa":"مورد نیاز است","examples":[{"de":"Für diese Stelle ist ein Studium erforderlich.","en":"A university degree is required for this position.","ru":"Для этой должности требуется высшее образование.","vi":"Vị trí này cần có bằng cấp.","fa":"مدرک تحصیلی برای این موقعیت الزامی است."},{"de":"Welche Unterlagen sind für den Antrag erforderlich?","en":"Which documents are required for the application?","ru":"Какие документы необходимы для заявления?","vi":"Những tài liệu cần thiết cho ứng dụng?","fa":"چه مدارکی برای درخواست نیاز است؟"}]},{"word":"erfordern","en":"to require","ru":"требовать (чего-л.)","vi":"yêu cầu","fa":"نیاز دارند","examples":[{"de":"Diese Arbeit erfordert viel Geduld.","en":"This work requires a lot of patience.","ru":"Эта работа требует много терпения.","vi":"Công việc này đòi hỏi rất nhiều sự kiên nhẫn.","fa":"این کار به صبر و حوصله زیادی نیاز دارد."},{"de":"Der Job erfordert gute Englischkenntnisse.","en":"The job requires good English skills.","ru":"Работа требует хорошего знания английского.","vi":"Công việc yêu cầu kỹ năng tiếng Anh tốt.","fa":"این شغل به مهارت خوب انگلیسی نیاز دارد."}]},{"word":"die Erfrischung","en":"refreshment","ru":"освежение, что-то освежающее","vi":"sự giải khát","fa":"طراوت","examples":[{"de":"An heißen Tagen ist ein kaltes Getränk eine echte Erfrischung.","en":"On hot days a cold drink is a real refreshment.","ru":"В жаркие дни холодный напиток — настоящее освежение.","vi":"Vào những ngày nắng nóng, một ly đồ uống lạnh thực sự là một sự giải khát.","fa":"در روزهای گرم، یک نوشیدنی سرد یک طراوت واقعی است."},{"de":"Zur Erfrischung gab es selbst gemachte Limonade.","en":"For refreshment there was homemade lemonade.","ru":"Для освежения был домашний лимонад.","vi":"Nước chanh tự làm có sẵn như một món giải khát.","fa":"لیموناد خانگی به عنوان طراوت در دسترس بود."},{"de":"Nach dem Sport brauche ich eine schnelle Erfrischung.","en":"After exercise I need a quick refreshment.","ru":"После спорта мне нужно быстро освежиться.","vi":"Sau khi tập thể dục tôi cần giải khát nhanh chóng.","fa":"بعد از ورزش من نیاز به یک طراوت سریع دارم."}]},{"word":"das Erfrischungsgetränk","en":"soft drink, refreshment","ru":"прохладительный напиток","vi":"nước giải khát","fa":"نوشابه","examples":[{"de":"An heißen Tagen trinke ich gern ein kühles Erfrischungsgetränk.","en":"On hot days I like to drink a cool soft drink.","ru":"В жаркие дни я люблю выпить прохладный напиток.","vi":"Vào những ngày nắng nóng tôi thích uống một thức uống giải khát mát lạnh.","fa":"در روزهای گرم من دوست دارم یک نوشیدنی خنک و خنک بنوشم."},{"de":"Im Sommer verkauft der Kiosk viele Erfrischungsgetränke.","en":"In summer the kiosk sells many soft drinks.","ru":"Летом киоск продаёт много прохладительных напитков.","vi":"Vào mùa hè ki-ốt bán nhiều nước ngọt.","fa":"در تابستان این کیوسک نوشیدنی‌های غیرالکلی زیادی می‌فروشد."},{"de":"Dieses Erfrischungsgetränk enthält leider viel Zucker.","en":"Unfortunately this soft drink contains a lot of sugar.","ru":"В этом напитке, к сожалению, много сахара.","vi":"Thật không may, loại nước giải khát này chứa rất nhiều đường.","fa":"متاسفانه این نوشابه حاوی مقدار زیادی قند است."}]},{"word":"erfüllen","en":"to fulfill","ru":"исполнять, выполнять","vi":"thực hiện","fa":"برآورده کند","examples":[{"de":"Er hat sich seinen Traum erfüllt.","en":"He fulfilled his dream.","ru":"Он исполнил свою мечту.","vi":"Anh ấy đã thực hiện được ước mơ của mình.","fa":"او به آرزویش رسیده است."},{"de":"Die Bewerberin erfüllt alle Voraussetzungen.","en":"The applicant fulfills all the requirements.","ru":"Соискательница соответствует всем требованиям.","vi":"Người nộp đơn đáp ứng tất cả các yêu cầu.","fa":"متقاضی تمام شرایط را دارد."}]},{"word":"ergänzen","en":"to complete, add to, supplement","ru":"дополнять","vi":"bổ sung","fa":"مکمل","examples":[{"de":"Bitte ergänzen Sie die fehlenden Wörter im Text.","en":"Please fill in the missing words in the text.","ru":"Пожалуйста, дополните недостающие слова в тексте.","vi":"Hãy điền những từ còn thiếu trong đoạn văn.","fa":"لطفا کلمات جا افتاده در متن را پر کنید."},{"de":"Die beiden Kollegen ergänzen sich gut.","en":"The two colleagues complement each other well.","ru":"Эти два коллеги хорошо дополняют друг друга.","vi":"Hai đồng nghiệp bổ sung cho nhau rất tốt.","fa":"این دو همکار به خوبی یکدیگر را تکمیل می کنند."}]},{"word":"das Ergebnis","en":"result","ru":"результат","vi":"kết quả","fa":"نتیجه","examples":[{"de":"Das Ergebnis der Prüfung war sehr gut.","en":"The result of the exam was very good.","ru":"Результат экзамена был очень хорошим.","vi":"Kết quả của bài kiểm tra là rất tốt.","fa":"نتیجه آزمایش خیلی خوب بود."},{"de":"Wir warten noch auf das Ergebnis der Untersuchung.","en":"We are still waiting for the result of the examination.","ru":"Мы всё ещё ждём результат обследования.","vi":"Chúng tôi vẫn đang chờ kết quả điều tra.","fa":"ما همچنان منتظر نتیجه تحقیقات هستیم."}]},{"word":"erhalten","en":"to receive; to preserve","ru":"получать; сохранять","vi":"đã nhận được","fa":"دریافت کرد","examples":[{"de":"Ich habe gestern deinen Brief erhalten.","en":"I received your letter yesterday.","ru":"Я вчера получил твоё письмо.","vi":"Tôi đã nhận được thư của bạn ngày hôm qua.","fa":"نامه شما را دیروز دریافت کردم."},{"de":"Wir müssen die Natur für die nächste Generation erhalten.","en":"We must preserve nature for the next generation.","ru":"Мы должны сохранить природу для следующего поколения.","vi":"Chúng ta phải bảo tồn thiên nhiên cho thế hệ tiếp theo.","fa":"ما باید طبیعت را برای نسل آینده حفظ کنیم."}]},{"word":"erheblich","en":"considerable; significant","ru":"значительный; существенный","vi":"đáng kể","fa":"بطور قابل توجهی","examples":[{"de":"Die Kosten sind erheblich gestiegen.","en":"The costs have risen considerably.","ru":"Расходы значительно возросли.","vi":"Các chi phí đã tăng lên đáng kể.","fa":"هزینه ها به میزان قابل توجهی افزایش یافته است."},{"de":"Es gibt einen erheblichen Unterschied zwischen den Angeboten.","en":"There is a significant difference between the offers.","ru":"Между предложениями есть существенная разница.","vi":"Có một sự khác biệt đáng kể giữa các ưu đãi.","fa":"تفاوت قابل توجهی بین پیشنهادات وجود دارد."}]},{"word":"erhöhen","en":"to raise, increase","ru":"повышать","vi":"tăng lên","fa":"افزایش دهد","examples":[{"de":"Der Vermieter will die Miete erhöhen.","en":"The landlord wants to raise the rent.","ru":"Арендодатель хочет повысить арендную плату.","vi":"Chủ nhà muốn tăng tiền thuê nhà.","fa":"صاحبخانه می خواهد اجاره بها را افزایش دهد."},{"de":"Sport kann die Konzentration erhöhen.","en":"Exercise can increase concentration.","ru":"Спорт может повысить концентрацию.","vi":"Tập thể dục có thể làm tăng sự tập trung.","fa":"ورزش می تواند تمرکز را افزایش دهد."}]},{"word":"die Erhöhung","en":"increase, raise","ru":"повышение, увеличение","vi":"sự gia tăng","fa":"افزایش","examples":[{"de":"Die Erhöhung der Preise hat viele Kunden verärgert.","en":"The increase in prices annoyed many customers.","ru":"Повышение цен разозлило многих клиентов.","vi":"Việc tăng giá khiến nhiều khách hàng bức xúc.","fa":"افزایش قیمت ها خشم بسیاری از مشتریان را برانگیخته است."},{"de":"Er hofft auf eine Erhöhung seines Gehalts.","en":"He is hoping for a raise in his salary.","ru":"Он надеется на повышение зарплаты.","vi":"Anh ấy đang hy vọng được tăng lương.","fa":"او امیدوار است حقوقش افزایش یابد."},{"de":"Eine Erhöhung der Steuern ist geplant.","en":"An increase in taxes is planned.","ru":"Планируется повышение налогов.","vi":"Việc tăng thuế đã được lên kế hoạch.","fa":"افزایش مالیات برنامه ریزی شده است."}]},{"word":"erholen","en":"to recover, to relax, to rest","ru":"отдыхать, восстанавливаться, расслабляться","vi":"phục hồi","fa":"بهبود می یابند","examples":[{"de":"Im Urlaub habe ich mich gut erholt.","en":"I recovered well during the holiday.","ru":"Я хорошо отдохнул во время отпуска.","vi":"Tôi đã phục hồi tốt trong kỳ nghỉ.","fa":"در تعطیلات خوب شدم."},{"de":"Du solltest dich nach der Krankheit erst richtig erholen.","en":"You should properly recover after the illness first.","ru":"Сначала тебе нужно как следует восстановиться после болезни.","vi":"Trước tiên bạn nên hồi phục đúng cách sau khi bị bệnh.","fa":"ابتدا باید پس از بیماری به طور مناسب بهبود پیدا کنید."},{"de":"Am Wochenende erholen wir uns am See.","en":"At the weekend we relax by the lake.","ru":"На выходных мы отдыхаем у озера.","vi":"Cuối tuần chúng tôi thư giãn ở hồ.","fa":"در آخر هفته در دریاچه استراحت می کنیم."}]},{"word":"die Erholung","en":"rest, recuperation, relaxation","ru":"отдых, восстановление","vi":"sự phục hồi","fa":"بهبودی","examples":[{"de":"Nach der harten Woche brauche ich dringend Erholung.","en":"After the hard week I urgently need some rest.","ru":"После тяжёлой недели мне срочно нужен отдых.","vi":"Sau một tuần vất vả, tôi cần được nghỉ ngơi gấp.","fa":"بعد از یک هفته سخت، نیاز فوری به استراحت دارم."},{"de":"Der Urlaub diente vor allem der Erholung.","en":"The holiday was mainly for relaxation.","ru":"Отпуск служил прежде всего для отдыха.","vi":"Kỳ nghỉ chủ yếu là để thư giãn.","fa":"تعطیلات در درجه اول برای استراحت بود."},{"de":"Im Wald findet man viel Ruhe und Erholung.","en":"In the forest you find a lot of peace and recuperation.","ru":"В лесу находишь много покоя и отдыха.","vi":"Bạn có thể tìm thấy rất nhiều sự bình yên và thư giãn trong rừng.","fa":"در جنگل می توانید آرامش و آرامش زیادی پیدا کنید."}]},{"word":"erinnern","en":"to remind; sich erinnern: to remember","ru":"напоминать; sich erinnern: вспоминать","vi":"nhớ","fa":"به یاد داشته باشید","examples":[{"de":"Kannst du mich morgen an den Termin erinnern?","en":"Can you remind me of the appointment tomorrow?","ru":"Можешь напомнить мне завтра о встрече?","vi":"Bạn có thể nhắc tôi về cuộc hẹn ngày mai được không?","fa":"میشه قرار فردا رو بهم یادآوری کنی؟"},{"de":"Ich erinnere mich gut an meine Kindheit.","en":"I remember my childhood well.","ru":"Я хорошо помню своё детство.","vi":"Tôi nhớ rất rõ thời thơ ấu của mình.","fa":"کودکی ام را خوب به یاد دارم."}]},{"word":"die Erinnerung","en":"memory; recollection","ru":"воспоминание","vi":"ký ức","fa":"حافظه","examples":[{"de":"Ich habe schöne Erinnerungen an meine Kindheit.","en":"I have fond memories of my childhood.","ru":"У меня приятные воспоминания о детстве.","vi":"Tôi có những kỷ niệm đẹp về thời thơ ấu của mình.","fa":"خاطرات خوبی از کودکی ام دارم."},{"de":"Zur Erinnerung an die Reise haben wir viele Fotos gemacht.","en":"As a memento of the trip, we took lots of photos.","ru":"На память о поездке мы сделали много фотографий.","vi":"Chúng tôi đã chụp rất nhiều ảnh để ghi nhớ chuyến đi.","fa":"برای یادآوری این سفر عکس های زیادی گرفتیم."}]},{"word":"erkälten","en":"to catch a cold","ru":"простужаться","vi":"bị cảm lạnh","fa":"سرماخوردگی","examples":[{"de":"Zieh dich warm an, sonst erkältest du dich.","en":"Dress warmly, otherwise you'll catch a cold.","ru":"Одевайся теплее, иначе простудишься.","vi":"Mặc ấm vào nếu không bạn sẽ bị cảm lạnh đấy.","fa":"لباس گرم بپوشید وگرنه سرما می خورید."},{"de":"Ich habe mich gestern im Regen erkältet.","en":"I caught a cold yesterday in the rain.","ru":"Я вчера простудился под дождём.","vi":"Hôm qua tôi bị cảm lạnh trong mưa.","fa":"دیروز زیر بارون سرما خوردم."},{"de":"Die Kinder haben sich beim Spielen draußen erkältet.","en":"The children caught a cold playing outside.","ru":"Дети простудились, играя на улице.","vi":"Trẻ em bị cảm lạnh khi chơi bên ngoài.","fa":"بچه ها هنگام بازی در بیرون سرما خوردند."}]},{"word":"die Erkältung","en":"cold (illness)","ru":"простуда","vi":"cái lạnh","fa":"سرما","examples":[{"de":"Ich habe eine schlimme Erkältung und bleibe zu Hause.","en":"I have a bad cold and am staying at home.","ru":"У меня сильная простуда, и я остаюсь дома.","vi":"Tôi bị cảm nặng và đang ở nhà.","fa":"من به شدت سرما خورده ام و در خانه می مانم."},{"de":"Bei einer Erkältung sollte man viel trinken.","en":"With a cold you should drink a lot.","ru":"При простуде нужно много пить.","vi":"Nếu bạn bị cảm lạnh, bạn nên uống nhiều.","fa":"اگر سرما خورده اید باید زیاد بنوشید."},{"de":"Die Erkältung dauerte fast zwei Wochen.","en":"The cold lasted almost two weeks.","ru":"Простуда длилась почти две недели.","vi":"Cái lạnh kéo dài gần hai tuần.","fa":"سرما تقریبا دو هفته طول کشید."}]},{"word":"erkennen","en":"to recognize","ru":"узнавать, распознавать","vi":"nhận ra","fa":"تشخیص دهد","examples":[{"de":"Ich habe ihn sofort erkannt, obwohl er sich verändert hat.","en":"I recognized him immediately, even though he has changed.","ru":"Я сразу его узнал, хотя он изменился.","vi":"Tôi nhận ra anh ngay lập tức, mặc dù anh đã thay đổi.","fa":"با وجود اینکه تغییر کرده بود، بلافاصله او را شناختم."},{"de":"Man kann das Problem schnell erkennen.","en":"One can quickly recognize the problem.","ru":"Проблему можно быстро распознать.","vi":"Bạn có thể nhanh chóng xác định vấn đề.","fa":"می توانید به سرعت مشکل را شناسایی کنید."}]},{"word":"erklären","en":"to explain","ru":"объяснять","vi":"giải thích","fa":"توضیح دهید","examples":[{"de":"Der Lehrer erklärt die Grammatik sehr gut.","en":"The teacher explains the grammar very well.","ru":"Учитель очень хорошо объясняет грамматику.","vi":"Thầy giảng ngữ pháp rất hay.","fa":"معلم گرامر را خیلی خوب توضیح می دهد."},{"de":"Kannst du mir erklären, wie das Gerät funktioniert?","en":"Can you explain to me how the device works?","ru":"Можешь объяснить мне, как работает это устройство?","vi":"Bạn có thể giải thích cho tôi cách hoạt động của thiết bị không?","fa":"میشه برام توضیح بدید دستگاه چطور کار میکنه؟"}]},{"word":"die Erklärung","en":"explanation","ru":"объяснение, пояснение","vi":"lời giải thích","fa":"توضیح","examples":[{"de":"Die Lehrerin gab eine klare Erklärung der Aufgabe.","en":"The teacher gave a clear explanation of the task.","ru":"Учительница дала чёткое объяснение задания.","vi":"Giáo viên giải thích rõ ràng nhiệm vụ.","fa":"معلم توضیح واضحی در مورد تکلیف داد."},{"de":"Für sein Verhalten gibt es keine Erklärung.","en":"There is no explanation for his behaviour.","ru":"Его поведению нет объяснения.","vi":"Không có lời giải thích nào cho hành vi của anh ta.","fa":"هیچ توضیحی برای رفتار او وجود ندارد."},{"de":"Können Sie mir eine genauere Erklärung geben?","en":"Can you give me a more precise explanation?","ru":"Можете дать мне более точное объяснение?","vi":"Bạn có thể cho tôi một lời giải thích chi tiết hơn?","fa":"میشه توضیح دقیق تری بدی؟"}]},{"word":"erkundigen","en":"to enquire, to ask for information","ru":"справляться, наводить справки, узнавать","vi":"hỏi thăm","fa":"پرس و جو کنید","examples":[{"de":"Ich möchte mich nach den Öffnungszeiten erkundigen.","en":"I would like to enquire about the opening hours.","ru":"Я хотел бы узнать о часах работы.","vi":"Tôi muốn hỏi về thời gian mở cửa.","fa":"من می خواهم در مورد زمان باز کردن پرس و جو کنم."},{"de":"Hast du dich schon nach einem Hotel erkundigt?","en":"Have you already enquired about a hotel?","ru":"Ты уже навёл справки об отеле?","vi":"Bạn đã hỏi về khách sạn chưa?","fa":"آیا قبلاً در مورد هتل پرس و جو کرده اید؟"},{"de":"Sie erkundigte sich höflich nach meiner Gesundheit.","en":"She politely asked after my health.","ru":"Она вежливо справилась о моём здоровье.","vi":"Cô ấy lịch sự hỏi thăm sức khỏe của tôi.","fa":"او مودبانه جویای سلامتی من شد."}]},{"word":"erlauben","en":"to allow, permit","ru":"разрешать","vi":"cho phép","fa":"اجازه می دهد","examples":[{"de":"Meine Eltern erlauben mir, am Wochenende länger auszugehen.","en":"My parents allow me to go out longer on weekends.","ru":"Родители разрешают мне гулять дольше по выходным.","vi":"Bố mẹ tôi cho phép tôi đi chơi lâu hơn vào cuối tuần.","fa":"والدینم به من اجازه می دهند آخر هفته ها بیشتر بیرون بروم."},{"de":"Rauchen ist hier nicht erlaubt.","en":"Smoking is not allowed here.","ru":"Курить здесь не разрешается.","vi":"Hút thuốc không được phép ở đây.","fa":"سیگار کشیدن در اینجا ممنوع است."}]},{"word":"die Erlaubnis","en":"permission","ru":"разрешение","vi":"sự cho phép","fa":"اجازه","examples":[{"de":"Du brauchst eine Erlaubnis.","en":"You need permission.","ru":"Тебе нужно разрешение.","vi":"Bạn cần sự cho phép.","fa":"شما نیاز به اجازه دارید."},{"de":"Ohne Erlaubnis darfst du nicht hinein.","en":"You may not go in without permission.","ru":"Без разрешения тебе нельзя входить.","vi":"Bạn không được phép vào mà không có sự cho phép.","fa":"شما بدون اجازه اجازه ورود ندارید."},{"de":"Die Eltern gaben ihre Erlaubnis.","en":"The parents gave their permission.","ru":"Родители дали своё разрешение.","vi":"Cha mẹ đã cho phép.","fa":"پدر و مادر اجازه دادند."}]},{"word":"erleben","en":"to experience","ru":"переживать, испытывать (событие)","vi":"kinh nghiệm","fa":"تجربه","examples":[{"de":"Wir haben im Urlaub viele schöne Dinge erlebt.","en":"We experienced many wonderful things on vacation.","ru":"В отпуске мы пережили много прекрасных моментов.","vi":"Chúng tôi đã trải nghiệm nhiều điều đẹp đẽ trong kỳ nghỉ.","fa":"ما در تعطیلات چیزهای زیبایی را تجربه کردیم."},{"de":"Er hat den Krieg als Kind erlebt.","en":"He experienced the war as a child.","ru":"Он пережил войну ребёнком.","vi":"Ông đã trải qua chiến tranh khi còn nhỏ.","fa":"او جنگ را از کودکی تجربه کرد."}]},{"word":"das Erlebnis","en":"experience (event one lives through)","ru":"впечатление, переживание, приключение","vi":"trải nghiệm","fa":"تجربه","examples":[{"de":"Die Reise war ein unvergessliches Erlebnis.","en":"The trip was an unforgettable experience.","ru":"Поездка была незабываемым впечатлением.","vi":"Chuyến đi là một trải nghiệm khó quên.","fa":"سفر تجربه ای فراموش نشدنی بود."},{"de":"Erzähl mir von deinem schönsten Erlebnis.","en":"Tell me about your nicest experience.","ru":"Расскажи мне о своём самом ярком впечатлении.","vi":"Hãy kể cho tôi nghe về trải nghiệm đẹp nhất của bạn.","fa":"از زیباترین تجربه خود بگویید."},{"de":"Das Konzert war für die Kinder ein großes Erlebnis.","en":"The concert was a great experience for the children.","ru":"Концерт был для детей большим событием.","vi":"Buổi hòa nhạc là một trải nghiệm tuyệt vời đối với các em.","fa":"این کنسرت برای بچه ها تجربه خوبی بود."}]},{"word":"erledigen","en":"to take care of, complete (a task)","ru":"выполнять, улаживать (дело)","vi":"làm","fa":"انجام دهید","examples":[{"de":"Ich muss noch ein paar Einkäufe erledigen.","en":"I still need to take care of some shopping.","ru":"Мне ещё нужно сделать кое-какие покупки.","vi":"Tôi vẫn phải đi mua sắm.","fa":"هنوز باید خرید کنم."},{"de":"Hast du die Aufgabe schon erledigt?","en":"Have you already completed the task?","ru":"Ты уже выполнил задание?","vi":"Bạn đã hoàn thành nhiệm vụ chưa?","fa":"آیا قبلاً کار را انجام داده اید؟"}]},{"word":"die Erledigung","en":"errand, completion (of a task)","ru":"поручение, дело; выполнение (задачи)","vi":"sự hoàn thành","fa":"تکمیل","examples":[{"de":"Am Samstag habe ich viele Erledigungen in der Stadt.","en":"On Saturday I have lots of errands to run in town.","ru":"В субботу у меня много дел в городе.","vi":"Vào thứ bảy, tôi có rất nhiều việc phải làm ở thành phố.","fa":"شنبه کارهای زیادی در شهر دارم."},{"de":"Die Erledigung der Post dauert nur fünf Minuten.","en":"Dealing with the post takes only five minutes.","ru":"Разобраться с почтой занимает всего пять минут.","vi":"Thư chỉ mất năm phút để hoàn thành.","fa":"نامه فقط پنج دقیقه طول می کشد تا تکمیل شود."},{"de":"Vielen Dank für die schnelle Erledigung meines Auftrags.","en":"Thank you for dealing with my order so quickly.","ru":"Спасибо за быстрое выполнение моего заказа.","vi":"Cảm ơn bạn đã hoàn thành đơn hàng của tôi một cách nhanh chóng.","fa":"ممنون از اینکه سریع سفارشم را تکمیل کردید"}]},{"word":"erleichtern","en":"to make easier, ease","ru":"облегчать","vi":"tạo điều kiện thuận lợi","fa":"تسهیل کند","examples":[{"de":"Der neue Computer erleichtert uns die Arbeit.","en":"The new computer makes our work easier.","ru":"Новый компьютер облегчает нам работу.","vi":"Máy tính mới làm cho công việc của chúng tôi dễ dàng hơn.","fa":"کامپیوتر جدید کار ما را آسان می کند."},{"de":"Diese App erleichtert das Lernen von Vokabeln.","en":"This app makes learning vocabulary easier.","ru":"Это приложение облегчает изучение слов.","vi":"Ứng dụng này giúp việc học từ vựng dễ dàng hơn.","fa":"این برنامه یادگیری لغات را آسان تر می کند."}]},{"word":"die Ermäßigung","en":"discount, reduction (in price)","ru":"скидка","vi":"giảm giá","fa":"تخفیف","examples":[{"de":"Studenten bekommen eine Ermäßigung auf den Eintritt.","en":"Students get a discount on admission.","ru":"Студенты получают скидку на вход.","vi":"Sinh viên được giảm giá khi nhập học.","fa":"دانشجویان در پذیرش از تخفیف برخوردار می شوند."},{"de":"Gibt es eine Ermäßigung für Kinder?","en":"Is there a discount for children?","ru":"Есть ли скидка для детей?","vi":"Có giảm giá cho trẻ em không?","fa":"برای بچه ها تخفیف داره؟"}]},{"word":"ermöglichen","en":"to make possible; to enable","ru":"делать возможным; позволять","vi":"kích hoạt","fa":"فعال کردن","examples":[{"de":"Ein Stipendium ermöglichte ihr das Studium im Ausland.","en":"A scholarship made it possible for her to study abroad.","ru":"Стипендия позволила ей учиться за границей.","vi":"Một học bổng đã giúp cô đi du học.","fa":"بورسیه تحصیلی او را قادر به تحصیل در خارج از کشور کرد."},{"de":"Neue Technik ermöglicht schnelleres Arbeiten.","en":"New technology enables faster work.","ru":"Новые технологии позволяют работать быстрее.","vi":"Công nghệ mới cho phép làm việc nhanh hơn.","fa":"فناوری جدید کار سریعتر را امکان پذیر می کند."}]},{"word":"ernähren","en":"to feed, nourish; sich ernähren: to eat, feed oneself","ru":"кормить; sich ernähren: питаться","vi":"nuôi dưỡng","fa":"تغذیه کردن","examples":[{"de":"Sie ernährt ihre Familie mit dem Geld aus zwei Jobs.","en":"She feeds her family with money from two jobs.","ru":"Она содержит семью на деньги с двух работ.","vi":"Cô hỗ trợ gia đình bằng số tiền từ hai công việc.","fa":"او با پول دو شغل خرج خانواده اش را می دهد."},{"de":"Er ernährt sich sehr gesund.","en":"He eats very healthily.","ru":"Он питается очень здорово.","vi":"Anh ấy ăn uống rất khỏe mạnh.","fa":"او خیلی سالم غذا می خورد."}]},{"word":"die Ernährung","en":"nutrition; diet","ru":"питание","vi":"chế độ ăn kiêng","fa":"رژیم غذایی","examples":[{"de":"Eine gesunde Ernährung ist die halbe Miete.","en":"A healthy diet is half the battle.","ru":"Здоровое питание — это уже половина дела.","vi":"Một chế độ ăn uống lành mạnh là một nửa trận chiến.","fa":"یک رژیم غذایی سالم نیمی از کار است."},{"de":"Er achtet sehr auf seine Ernährung.","en":"He pays close attention to his diet.","ru":"Он очень внимательно относится к своему питанию.","vi":"Anh ấy rất chú ý đến chế độ ăn uống của mình.","fa":"او به رژیم غذایی خود اهمیت زیادی می دهد."}]},{"word":"erneuerbar","en":"renewable","ru":"возобновляемый","vi":"tái tạo","fa":"قابل تجدید","examples":[{"de":"Sonne und Wind sind erneuerbare Energiequellen.","en":"Sun and wind are renewable energy sources.","ru":"Солнце и ветер — возобновляемые источники энергии.","vi":"Mặt trời và gió là nguồn năng lượng tái tạo.","fa":"خورشید و باد منابع انرژی تجدیدپذیر هستند."},{"de":"Immer mehr Strom kommt aus erneuerbaren Quellen.","en":"More and more electricity comes from renewable sources.","ru":"Всё больше электроэнергии поступает из возобновляемых источников.","vi":"Ngày càng có nhiều điện đến từ các nguồn tái tạo.","fa":"برق بیشتر و بیشتر از منابع تجدید پذیر تامین می شود."}]},{"word":"erneuern","en":"to renew, to renovate, to replace","ru":"обновлять, заменять, ремонтировать","vi":"gia hạn","fa":"تجدید","examples":[{"de":"Ich muss meinen Ausweis bald erneuern.","en":"I have to renew my ID card soon.","ru":"Мне скоро нужно обновить удостоверение личности.","vi":"Tôi phải gia hạn ID của mình sớm.","fa":"من باید به زودی شناسنامه ام را تمدید کنم."},{"de":"Die Stadt erneuert die alten Wasserleitungen.","en":"The city is replacing the old water pipes.","ru":"Город заменяет старые водопроводные трубы.","vi":"Thành phố đang thay thế các đường ống nước cũ.","fa":"شهر در حال تعویض لوله های قدیمی آب است."},{"de":"Wir haben den Vertrag um ein weiteres Jahr erneuert.","en":"We renewed the contract for another year.","ru":"Мы продлили договор ещё на год.","vi":"Chúng tôi đã gia hạn hợp đồng thêm một năm nữa.","fa":"قرارداد را برای یک سال دیگر تمدید کردیم."}]},{"word":"ernst","en":"serious","ru":"серьёзный","vi":"nghiêm túc","fa":"به طور جدی","examples":[{"de":"Das ist eine ernste Angelegenheit.","en":"This is a serious matter.","ru":"Это серьёзное дело.","vi":"Đây là một vấn đề nghiêm trọng.","fa":"این یک موضوع جدی است."},{"de":"Er sah plötzlich sehr ernst aus.","en":"He suddenly looked very serious.","ru":"Он вдруг стал выглядеть очень серьёзно.","vi":"Anh ấy đột nhiên trông rất nghiêm túc.","fa":"او ناگهان بسیار جدی به نظر می رسد."}]},{"word":"ernsthaft","en":"serious, in earnest, genuinely","ru":"серьёзный, всерьёз, по-настоящему","vi":"nghiêm túc","fa":"به طور جدی","examples":[{"de":"Wir denken ernsthaft über einen Umzug nach.","en":"We are seriously thinking about moving.","ru":"Мы всерьёз думаем о переезде.","vi":"Chúng tôi đang nghiêm túc xem xét việc di chuyển.","fa":"ما به طور جدی در حال بررسی جابجایی هستیم."},{"de":"Sie hat ernsthafte Probleme mit ihrem Auto.","en":"She has serious problems with her car.","ru":"У неё серьёзные проблемы с машиной.","vi":"Cô ấy có vấn đề nghiêm trọng với chiếc xe của mình.","fa":"او با ماشینش مشکلات جدی دارد."},{"de":"Bist du ernsthaft sauer auf mich?","en":"Are you genuinely angry with me?","ru":"Ты по-настоящему злишься на меня?","vi":"Bạn có thực sự giận tôi không?","fa":"جدی از دست من عصبانی هستی؟"}]},{"word":"die Ernte","en":"harvest","ru":"урожай","vi":"thu hoạch","fa":"برداشت","examples":[{"de":"Die Bauern sind mit der Ernte beschäftigt.","en":"The farmers are busy with the harvest.","ru":"Фермеры заняты сбором урожая.","vi":"Nông dân đang tất bật thu hoạch.","fa":"کشاورزان مشغول برداشت محصول هستند."},{"de":"Dieses Jahr war die Ernte besonders gut.","en":"This year the harvest was especially good.","ru":"В этом году урожай был особенно хорошим.","vi":"Năm nay thu hoạch đặc biệt tốt.","fa":"امسال برداشت به ویژه خوب بود."}]},{"word":"die Eroberung","en":"conquest","ru":"завоевание, покорение","vi":"cuộc chinh phục","fa":"the conquest","examples":[{"de":"Die Eroberung der Stadt veränderte die Machtverhältnisse.","en":"The conquest of the city changed the balance of power.","ru":"Завоевание города изменило расстановку сил.","vi":"Cuộc chinh phục thành phố đã thay đổi cán cân quyền lực.","fa":"فتح شهر توازن قوا را تغییر داد."},{"de":"Nach der Eroberung wurde eine neue Sprache eingeführt.","en":"After the conquest a new language was introduced.","ru":"После завоевания был введён новый язык.","vi":"Sau cuộc chinh phục, một ngôn ngữ mới đã được giới thiệu.","fa":"پس از فتح، زبان جدیدی معرفی شد."},{"de":"Die Eroberung neuer Gebiete machte das Reich größer.","en":"The conquest of new territories made the empire larger.","ru":"Завоевание новых земель увеличило империю.","vi":"Cuộc chinh phục các vùng lãnh thổ mới làm cho đế chế trở nên lớn mạnh hơn.","fa":"فتح مناطق جدید امپراتوری را بزرگتر کرد."}]},{"word":"eröffnen","en":"to open (a business, account, exhibition)","ru":"открывать (бизнес, счёт, выставку)","vi":"mở","fa":"باز کردن","examples":[{"de":"Sie hat letzten Monat ein neues Geschäft eröffnet.","en":"She opened a new shop last month.","ru":"В прошлом месяце она открыла новый магазин.","vi":"Cô ấy đã mở một cửa hàng mới vào tháng trước.","fa":"او ماه گذشته یک فروشگاه جدید افتتاح کرد."},{"de":"Ich möchte ein Konto bei dieser Bank eröffnen.","en":"I would like to open an account at this bank.","ru":"Я хотел бы открыть счёт в этом банке.","vi":"Tôi muốn mở một tài khoản ở ngân hàng này.","fa":"من می خواهم در این بانک حساب باز کنم."}]},{"word":"die Eröffnung","en":"opening (of an event, shop, etc.)","ru":"открытие (события, магазина и т. п.)","vi":"sự mở đầu","fa":"افتتاحیه","examples":[{"de":"Die Eröffnung des neuen Geschäfts findet am Samstag statt.","en":"The opening of the new shop takes place on Saturday.","ru":"Открытие нового магазина состоится в субботу.","vi":"Việc khai trương cửa hàng mới sẽ diễn ra vào thứ bảy.","fa":"افتتاحیه فروشگاه جدید روز شنبه انجام می شود."},{"de":"Zur Eröffnung der Ausstellung kamen viele Gäste.","en":"Many guests came to the opening of the exhibition.","ru":"На открытие выставки пришло много гостей.","vi":"Đông đảo khách mời đến dự khai mạc triển lãm.","fa":"مهمانان زیادی به افتتاحیه نمایشگاه آمدند."},{"de":"Die feierliche Eröffnung wurde live übertragen.","en":"The ceremonial opening was broadcast live.","ru":"Торжественное открытие транслировали вживую.","vi":"Lễ khai trương được truyền hình trực tiếp.","fa":"افتتاحیه به صورت زنده پخش شد."}]},{"word":"erreichen","en":"to reach, achieve","ru":"достигать","vi":"đạt được","fa":"رسیدن","examples":[{"de":"Wir haben unser Ziel endlich erreicht.","en":"We have finally reached our goal.","ru":"Мы наконец достигли своей цели.","vi":"Cuối cùng chúng tôi đã đạt được mục tiêu của mình.","fa":"بالاخره به هدفمون رسیدیم."},{"de":"Ich kann ihn telefonisch nicht erreichen.","en":"I can't reach him by phone.","ru":"Я не могу дозвониться до него.","vi":"Tôi không thể liên lạc với anh ấy qua điện thoại.","fa":"با تلفن نمی توانم با او تماس بگیرم."}]},{"word":"der Ersatz","en":"replacement, substitute","ru":"замена, замещение","vi":"sự thay thế","fa":"جایگزینی","examples":[{"de":"Wir suchen einen Ersatz für den kaputten Drucker.","en":"We are looking for a replacement for the broken printer.","ru":"Мы ищем замену сломанному принтеру.","vi":"Chúng tôi đang tìm kiếm một sự thay thế cho máy in bị hỏng.","fa":"ما به دنبال جایگزینی برای چاپگر خراب هستیم."},{"de":"Als Ersatz für Zucker benutzt sie Honig.","en":"As a substitute for sugar she uses honey.","ru":"В качестве замены сахара она использует мёд.","vi":"Cô sử dụng mật ong thay thế cho đường.","fa":"او از عسل به عنوان جایگزین شکر استفاده می کند."},{"de":"Für den kranken Spieler kam ein Ersatz aufs Feld.","en":"A substitute came onto the field for the injured player.","ru":"Вместо травмированного игрока на поле вышел запасной.","vi":"Cầu thủ bị ốm đã được tung vào sân.","fa":"جایگزینی برای بازیکن بیمار وارد زمین شد."}]},{"word":"erschöpft","en":"exhausted","ru":"измождённый, истощённый","vi":"kiệt sức","fa":"خسته","examples":[{"de":"Nach dem Marathon war sie völlig erschöpft.","en":"After the marathon she was completely exhausted.","ru":"После марафона она была совершенно измотана.","vi":"Sau cuộc chạy marathon cô ấy hoàn toàn kiệt sức.","fa":"پس از ماراتن او کاملا خسته بود."},{"de":"Ich bin heute Abend total erschöpft von der Arbeit.","en":"I am totally exhausted from work this evening.","ru":"Сегодня вечером я совершенно измотан работой.","vi":"Tôi hoàn toàn kiệt sức vì làm việc tối nay.","fa":"امروز عصر کاملا از سر کار خسته شدم."}]},{"word":"erschrecken","en":"to be startled, frightened","ru":"пугаться","vi":"sợ hãi","fa":"ترساندن","examples":[{"de":"Ich bin erschrocken, als das Telefon plötzlich klingelte.","en":"I got startled when the phone suddenly rang.","ru":"Я испугался, когда вдруг зазвонил телефон.","vi":"Tôi giật mình khi điện thoại đột nhiên reo lên.","fa":"وقتی ناگهان تلفن زنگ خورد، از جا پریدم."},{"de":"Sie erschrickt leicht bei lauten Geräuschen.","en":"She gets startled easily by loud noises.","ru":"Она легко пугается громких звуков.","vi":"Cô ấy dễ bị giật mình bởi những tiếng động lớn.","fa":"او به راحتی با صداهای بلند مبهوت می شود."}]},{"word":"ersetzen","en":"to replace","ru":"заменять","vi":"thay thế","fa":"جایگزین کنید","examples":[{"de":"Wir müssen den alten Drucker ersetzen.","en":"We need to replace the old printer.","ru":"Нам нужно заменить старый принтер.","vi":"Chúng ta cần thay thế máy in cũ.","fa":"باید چاپگر قدیمی را تعویض کنیم."},{"de":"Kein Buch kann persönliche Erfahrung ersetzen.","en":"No book can replace personal experience.","ru":"Ни одна книга не может заменить личный опыт.","vi":"Không có cuốn sách nào có thể thay thế được trải nghiệm cá nhân.","fa":"هیچ کتابی نمی تواند جایگزین تجربه شخصی شود."}]},{"word":"erst","en":"only, not until (temporal); first","ru":"только, лишь (о времени); сначала","vi":"đầu tiên","fa":"اول","examples":[{"de":"Der Zug kommt erst um 18 Uhr an.","en":"The train doesn't arrive until 6 p.m.","ru":"Поезд прибывает только в 18 часов.","vi":"Xe lửa không đến cho đến 6 giờ chiều.","fa":"قطار تا ساعت 6 عصر نمی رسد."},{"de":"Ich bin erst seit einer Woche hier.","en":"I've only been here for a week.","ru":"Я здесь только неделю.","vi":"Tôi mới ở đây được một tuần.","fa":"من فقط یک هفته اینجا هستم"}]},{"word":"erst-","en":"first (stem meaning 'first')","ru":"перво- (основа со значением 'первый')","vi":"đầu tiên-","fa":"اول -","examples":[{"de":"Das Hotel bietet einen erstklassigen Service.","en":"The hotel offers first-class service.","ru":"Отель предлагает первоклассный сервис.","vi":"Khách sạn cung cấp dịch vụ hạng nhất.","fa":"این هتل خدمات درجه یک ارائه می دهد."},{"de":"Dieses Restaurant serviert erstklassiges Essen.","en":"This restaurant serves first-class food.","ru":"Этот ресторан подаёт первоклассную еду.","vi":"Nhà hàng này phục vụ các món ăn chất lượng hàng đầu.","fa":"این رستوران غذاهایی با کیفیت عالی سرو می کند."}]},{"word":"der Erste-Hilfe-Kurs","en":"first-aid course","ru":"курс первой помощи","vi":"khóa học sơ cứu","fa":"دوره کمک های اولیه","examples":[{"de":"Vor der Führerscheinprüfung muss man einen Erste-Hilfe-Kurs machen.","en":"Before the driving test you have to take a first-aid course.","ru":"Перед экзаменом на права нужно пройти курс первой помощи.","vi":"Trước khi thi lái xe, bạn phải tham gia khóa học sơ cứu.","fa":"قبل از شرکت در آزمون رانندگی باید یک دوره کمک های اولیه را بگذرانید."},{"de":"Im Erste-Hilfe-Kurs lernt man, wie man Verletzten hilft.","en":"In the first-aid course you learn how to help injured people.","ru":"На курсе первой помощи учат, как помогать пострадавшим.","vi":"Trong khóa học sơ cứu, bạn học cách giúp đỡ người bị thương.","fa":"در دوره کمک های اولیه یاد می گیرید که چگونه به افراد آسیب دیده کمک کنید."},{"de":"Der Erste-Hilfe-Kurs dauert nur einen Tag.","en":"The first-aid course lasts only one day.","ru":"Курс первой помощи длится всего один день.","vi":"Khóa học sơ cứu chỉ kéo dài một ngày.","fa":"دوره کمک های اولیه فقط یک روز طول می کشد."}]},{"word":"erstellen","en":"to create, draw up (a document, plan)","ru":"составлять, создавать (документ)","vi":"tạo ra","fa":"ایجاد کنید","examples":[{"de":"Der Architekt erstellt einen Plan für das neue Haus.","en":"The architect draws up a plan for the new house.","ru":"Архитектор составляет план нового дома.","vi":"Kiến trúc sư tạo ra một kế hoạch cho ngôi nhà mới.","fa":"معمار نقشه ای برای خانه جدید ایجاد می کند."},{"de":"Ich muss noch eine Liste für den Einkauf erstellen.","en":"I still need to create a list for shopping.","ru":"Мне ещё нужно составить список покупок.","vi":"Tôi vẫn phải lập danh sách mua sắm.","fa":"من هنوز باید یک لیست خرید تهیه کنم."}]},{"word":"erwachsen","en":"grown-up, adult","ru":"взрослый (прил.)","vi":"người lớn","fa":"بالغ","examples":[{"de":"Seine Kinder sind schon erwachsen.","en":"His children are already grown up.","ru":"Его дети уже взрослые.","vi":"Các con của anh đều đã trưởng thành rồi.","fa":"فرزندان او در حال حاضر بالغ هستند."},{"de":"Sie benimmt sich sehr erwachsen für ihr Alter.","en":"She behaves very maturely for her age.","ru":"Она ведёт себя очень по-взрослому для своего возраста.","vi":"Cô ấy hành động rất chững chạc so với tuổi của mình.","fa":"او نسبت به سنش بسیار بالغ عمل می کند."}]},{"word":"der Erwachsene","en":"adult (person)","ru":"взрослый (человек)","vi":"người lớn","fa":"بزرگسال","examples":[{"de":"Der Eintritt kostet für Erwachsene zehn Euro.","en":"Admission costs ten euros for adults.","ru":"Вход стоит десять евро для взрослых.","vi":"Vé vào cửa có giá 10 euro cho người lớn.","fa":"هزینه ورودی برای بزرگسالان ده یورو است."},{"de":"Dieser Film ist nur für Erwachsene geeignet.","en":"This movie is suitable only for adults.","ru":"Этот фильм подходит только для взрослых.","vi":"Phim này chỉ phù hợp với người lớn thôi.","fa":"این فیلم فقط برای بزرگسالان مناسب است."}]},{"word":"erwähnen","en":"to mention","ru":"упоминать","vi":"đề cập đến","fa":"ذکر کنید","examples":[{"de":"Sie hat mit keinem Wort das Problem erwähnt.","en":"She didn't mention the problem with a single word.","ru":"Она ни словом не упомянула о проблеме.","vi":"Cô ấy không đề cập đến vấn đề gì cả.","fa":"او اصلاً به مشکل اشاره نکرد."},{"de":"Wie ich schon erwähnt habe, fängt die Sitzung um zehn an.","en":"As I already mentioned, the meeting starts at ten.","ru":"Как я уже упомянул, собрание начинается в десять.","vi":"Như tôi đã đề cập, cuộc họp bắt đầu lúc 10 giờ.","fa":"همانطور که اشاره کردم جلسه ساعت ده شروع می شود."}]},{"word":"erwärmen","en":"to warm up, to heat","ru":"нагревать, согревать","vi":"hâm nóng","fa":"گرم کردن","examples":[{"de":"Die Treibhausgase erwärmen die Atmosphäre.","en":"The greenhouse gases warm the atmosphere.","ru":"Парниковые газы нагревают атмосферу.","vi":"Khí nhà kính làm ấm bầu không khí.","fa":"گازهای گلخانه ای جو را گرم می کنند."},{"de":"Die Ozeane erwärmen sich immer schneller.","en":"The oceans are warming up faster and faster.","ru":"Океаны нагреваются всё быстрее.","vi":"Các đại dương đang nóng lên nhanh hơn bao giờ hết.","fa":"اقیانوس ها سریع تر گرم می شوند."},{"de":"Die Sonne erwärmt das Wasser im See.","en":"The sun warms the water in the lake.","ru":"Солнце нагревает воду в озере.","vi":"Mặt trời làm ấm nước trong hồ.","fa":"خورشید آب دریاچه را گرم می کند."}]},{"word":"die Erwärmung","en":"warming","ru":"потепление","vi":"sự nóng lên","fa":"گرم شدن","examples":[{"de":"Die globale Erwärmung lässt die Gletscher schmelzen.","en":"Global warming is melting the glaciers.","ru":"Глобальное потепление растапливает ледники.","vi":"Sự nóng lên toàn cầu đang khiến các sông băng tan chảy.","fa":"گرم شدن کره زمین باعث آب شدن یخچال های طبیعی می شود."},{"de":"Schon eine kleine Erwärmung kann große Folgen haben.","en":"Even a small amount of warming can have major consequences.","ru":"Даже небольшое потепление может иметь серьёзные последствия.","vi":"Ngay cả một lượng nhỏ sự nóng lên cũng có thể gây ra hậu quả lớn.","fa":"حتی مقدار کمی گرم شدن می تواند عواقب بزرگی داشته باشد."}]},{"word":"erwarten","en":"to expect","ru":"ожидать","vi":"mong đợi","fa":"انتظار می رود","examples":[{"de":"Wir erwarten Gäste zum Abendessen.","en":"We are expecting guests for dinner.","ru":"Мы ожидаем гостей к ужину.","vi":"Chúng tôi đang chờ khách đến ăn tối.","fa":"برای شام منتظر مهمان هستیم."},{"de":"Sie erwartet ein Kind im Herbst.","en":"She is expecting a baby in the fall.","ru":"Осенью она ждёт ребёнка.","vi":"Cô ấy đang mong đợi một đứa trẻ vào mùa thu.","fa":"او در پاییز در انتظار بچه دار شدن است."}]},{"word":"erwischen","en":"to catch, to manage to catch (informal)","ru":"ловить, застать; успеть (разг.)","vi":"bắt","fa":"گرفتن","examples":[{"de":"Der Lehrer hat ihn beim Abschreiben erwischt.","en":"The teacher caught him copying.","ru":"Учитель застал его за списыванием.","vi":"Giáo viên bắt gặp anh ta đang sao chép.","fa":"معلم او را در حال کپی گرفتن گرفت."},{"de":"Wenn wir uns beeilen, erwischen wir noch den Bus.","en":"If we hurry, we'll still catch the bus.","ru":"Если поторопимся, ещё успеем на автобус.","vi":"Nếu chúng ta nhanh lên, chúng ta sẽ bắt được xe buýt.","fa":"اگر عجله کنیم، اتوبوس را می گیریم."},{"de":"Leider habe ich nur noch einen schlechten Platz erwischt.","en":"Unfortunately I only managed to get a bad seat.","ru":"К сожалению, мне досталось плохое место.","vi":"Thật không may, tôi chỉ có một chỗ ngồi tồi.","fa":"متاسفانه من فقط یک صندلی بد گرفتم."}]},{"word":"erwünscht","en":"desired, wanted, welcome","ru":"желательный, желаемый, желанный","vi":"mong muốn","fa":"مورد نظر","examples":[{"de":"Eine Anmeldung ist erwünscht, aber nicht Pflicht.","en":"Registration is desired but not compulsory.","ru":"Регистрация желательна, но не обязательна.","vi":"Đăng ký là mong muốn, nhưng không bắt buộc.","fa":"ثبت نام مورد نظر است اما اجباری نیست."},{"de":"Kritik ist hier ausdrücklich erwünscht.","en":"Criticism is expressly welcome here.","ru":"Критика здесь прямо-таки приветствуется.","vi":"Sự chỉ trích được hoan nghênh rõ ràng ở đây.","fa":"در اینجا به صراحت از انتقاد پذیرفته می شود."},{"de":"Das Ergebnis war nicht der erwünschte Erfolg.","en":"The result was not the desired success.","ru":"Результат оказался не тем желаемым успехом.","vi":"Kết quả không phải là thành công như mong muốn.","fa":"نتیجه موفقیت مورد نظر نبود."}]},{"word":"erzählen","en":"to tell (a story), narrate","ru":"рассказывать","vi":"nói","fa":"بگو","examples":[{"de":"Meine Oma erzählt gerne Geschichten aus ihrer Jugend.","en":"My grandma likes to tell stories from her youth.","ru":"Моя бабушка любит рассказывать истории из своей молодости.","vi":"Bà tôi thích kể những câu chuyện thời trẻ của bà.","fa":"مادربزرگم دوست دارد از دوران جوانی خود قصه بگوید."},{"de":"Erzähl mir, wie dein Tag war.","en":"Tell me how your day was.","ru":"Расскажи мне, как прошёл твой день.","vi":"Hãy kể cho tôi nghe ngày hôm nay của bạn thế nào.","fa":"بگو روزت چطور بود"}]},{"word":"die Erzählung","en":"story, narrative, short story","ru":"рассказ, повествование","vi":"câu chuyện","fa":"روایت","examples":[{"de":"Diese Erzählung von Kafka ist sehr bekannt.","en":"This short story by Kafka is very well known.","ru":"Этот рассказ Кафки очень известен.","vi":"Câu chuyện này của Kafka rất nổi tiếng.","fa":"این داستان کافکا بسیار شناخته شده است."},{"de":"Die Erzählung des alten Mannes war spannend.","en":"The old man's story was exciting.","ru":"Рассказ старика был захватывающим.","vi":"Câu chuyện của ông già thật thú vị.","fa":"داستان پیرمرد هیجان انگیز بود."},{"de":"Wir lasen im Unterricht eine kurze Erzählung.","en":"In class we read a short story.","ru":"На уроке мы читали короткий рассказ.","vi":"Chúng tôi đọc một câu chuyện ngắn trong lớp.","fa":"در کلاس یک داستان کوتاه خواندیم."}]},{"word":"erziehen","en":"to raise, bring up (a child)","ru":"воспитывать","vi":"nuôi dạy","fa":"پرورش دادن","examples":[{"de":"Die Eltern erziehen ihre Kinder zur Selbstständigkeit.","en":"The parents raise their children to be independent.","ru":"Родители воспитывают детей самостоятельными.","vi":"Cha mẹ nuôi dạy con cái có tính tự lập.","fa":"والدین فرزندان خود را مستقل تربیت می کنند."},{"de":"Es ist nicht einfach, drei Kinder zu erziehen.","en":"It is not easy to raise three children.","ru":"Непросто воспитывать троих детей.","vi":"Nuôi ba đứa con không hề dễ dàng.","fa":"بزرگ کردن سه فرزند آسان نیست."}]},{"word":"die Erziehungsmethode","en":"parenting method","ru":"метод воспитания","vi":"phương pháp giáo dục","fa":"روش آموزشی","examples":[{"de":"Über die richtige Erziehungsmethode wird viel diskutiert.","en":"There is much debate about the right parenting method.","ru":"О правильном методе воспитания много спорят.","vi":"Có rất nhiều tranh luận về phương pháp nuôi dạy con đúng đắn.","fa":"بحث های زیادی در مورد روش صحیح فرزند پروری وجود دارد."},{"de":"Ihre Erziehungsmethode setzt auf Geduld und Vertrauen.","en":"Her parenting method relies on patience and trust.","ru":"Её метод воспитания опирается на терпение и доверие.","vi":"Phương pháp nuôi dạy con cái của cô dựa vào sự kiên nhẫn và tin tưởng.","fa":"روش فرزندپروری او متکی بر صبر و اعتماد است."},{"de":"Strenge Erziehungsmethoden sind heute weniger verbreitet.","en":"Strict parenting methods are less common today.","ru":"Строгие методы воспитания сегодня менее распространены.","vi":"Phương pháp nuôi dạy con nghiêm khắc ngày nay ít phổ biến hơn.","fa":"امروزه روش های سخت گیرانه فرزند پروری کمتر رایج است."}]},{"word":"es","en":"it","ru":"оно; это","vi":"nó","fa":"آن را","examples":[{"de":"Es regnet heute den ganzen Tag.","en":"It is raining all day today.","ru":"Сегодня весь день идёт дождь.","vi":"Hôm nay trời mưa cả ngày.","fa":"امروز تمام روز باران می بارد."},{"de":"Wo ist das Buch? Es liegt auf dem Tisch.","en":"Where is the book? It's on the table.","ru":"Где книга? Она лежит на столе.","vi":"Cuốn sách ở đâu? Nó ở trên bàn.","fa":"کتاب کجاست؟ روی میز است."}]},{"word":"Es kommt ganz darauf an","en":"It all depends (non-committal)","ru":"Всё зависит от обстоятельств (уклончиво)","vi":"Tất cả phụ thuộc","fa":"همه چیز بستگی دارد","examples":[{"de":"Es kommt ganz darauf an, wie das Wetter wird.","en":"It all depends on what the weather will be like.","ru":"Всё зависит от того, какая будет погода.","vi":"Tất cả phụ thuộc vào thời tiết như thế nào.","fa":"همه چیز بستگی به آب و هوا دارد."}]},{"word":"der Espresso","en":"espresso","ru":"эспрессо","vi":"cà phê espresso","fa":"اسپرسو","examples":[{"de":"Nach dem Mittagessen trinkt sie einen starken Espresso.","en":"After lunch she drinks a strong espresso.","ru":"После обеда она пьёт крепкий эспрессо.","vi":"Sau bữa trưa, cô ấy uống một tách espresso đậm đặc.","fa":"بعد از ناهار او یک اسپرسوی قوی می نوشد."},{"de":"Ein Espresso wird in einer kleinen Tasse serviert.","en":"An espresso is served in a small cup.","ru":"Эспрессо подают в маленькой чашке.","vi":"Cà phê espresso được phục vụ trong một cốc nhỏ.","fa":"یک اسپرسو در یک فنجان کوچک سرو می شود."},{"de":"Der Espresso war mir zu bitter.","en":"The espresso was too bitter for me.","ru":"Эспрессо был для меня слишком горьким.","vi":"Cà phê espresso quá đắng đối với tôi.","fa":"اسپرسو برای من خیلی تلخ بود."}]},{"word":"essbar","en":"edible","ru":"съедобный","vi":"ăn được","fa":"خوراکی","examples":[{"de":"Diese Pilze sind nicht essbar.","en":"These mushrooms are not edible.","ru":"Эти грибы несъедобны.","vi":"Những loại nấm này không ăn được.","fa":"این قارچ ها خوراکی نیستند."},{"de":"Sind diese Beeren überhaupt essbar?","en":"Are these berries even edible?","ru":"Эти ягоды вообще съедобны?","vi":"Những quả mọng này có ăn được không?","fa":"آیا این توت ها حتی خوراکی هستند؟"},{"de":"Nur der essbare Teil der Pflanze wird verwendet.","en":"Only the edible part of the plant is used.","ru":"Используется только съедобная часть растения.","vi":"Chỉ sử dụng phần ăn được của cây.","fa":"فقط از قسمت خوراکی گیاه استفاده می شود."}]},{"word":"essen","en":"to eat","ru":"есть, кушать","vi":"ăn","fa":"خوردن","examples":[{"de":"Wir essen jeden Abend gemeinsam zu Hause.","en":"We eat together at home every evening.","ru":"Мы каждый вечер вместе едим дома.","vi":"Chúng tôi ăn cùng nhau ở nhà vào mỗi buổi tối.","fa":"هر روز عصر با هم در خانه غذا می خوریم."},{"de":"Was möchtest du heute zu Mittag essen?","en":"What would you like to eat for lunch today?","ru":"Что ты хочешь съесть сегодня на обед?","vi":"Bạn muốn ăn gì cho bữa trưa hôm nay?","fa":"دوست داری امروز ناهار چی بخوری؟"}]},{"word":"die Essgewohnheit","en":"eating habit","ru":"пищевая привычка, привычки в еде","vi":"thói quen ăn uống","fa":"the eating habit","examples":[{"de":"Ihre Essgewohnheiten haben sich seit dem Umzug verändert.","en":"Her eating habits have changed since the move.","ru":"Её привычки в еде изменились после переезда.","vi":"Thói quen ăn uống của bạn đã thay đổi kể từ khi chuyển đi.","fa":"عادات غذایی شما از زمان حرکت تغییر کرده است."},{"de":"Gesunde Essgewohnheiten sind wichtig für den Körper.","en":"Healthy eating habits are important for the body.","ru":"Здоровые привычки в еде важны для организма.","vi":"Thói quen ăn uống lành mạnh rất quan trọng đối với cơ thể.","fa":"عادات غذایی سالم برای بدن مهم است."},{"de":"In jedem Land gibt es andere Essgewohnheiten.","en":"In every country there are different eating habits.","ru":"В каждой стране свои привычки в еде.","vi":"Mỗi quốc gia đều có thói quen ăn uống khác nhau.","fa":"هر کشوری عادات غذایی متفاوتی دارد."}]},{"word":"der Essig","en":"vinegar","ru":"уксус","vi":"giấm","fa":"سرکه","examples":[{"de":"Für den Salat brauchen wir Öl und Essig.","en":"For the salad we need oil and vinegar.","ru":"Для салата нам нужны масло и уксус.","vi":"Đối với món salad chúng ta cần dầu và giấm.","fa":"برای سالاد به روغن و سرکه نیاز داریم."},{"de":"Sie würzt die Soße mit etwas Essig.","en":"She seasons the sauce with a bit of vinegar.","ru":"Она приправляет соус небольшим количеством уксуса.","vi":"Cô nêm nước sốt với một ít giấm.","fa":"سس را با کمی سرکه مزه دار می کند."}]},{"word":"die Etage","en":"floor, storey","ru":"этаж","vi":"sàn nhà","fa":"کف","examples":[{"de":"Unsere Wohnung liegt in der dritten Etage.","en":"Our apartment is on the third floor.","ru":"Наша квартира находится на третьем этаже.","vi":"Căn hộ của chúng tôi ở trên tầng ba.","fa":"آپارتمان ما در طبقه سوم است."},{"de":"Der Aufzug fährt nicht in die oberste Etage.","en":"The elevator doesn't go to the top floor.","ru":"Лифт не едет на самый верхний этаж.","vi":"Thang máy không đi lên tầng trên cùng.","fa":"آسانسور به طبقه بالا نمی رود."}]},{"word":"etwa","en":"about, approximately","ru":"примерно, около","vi":"về","fa":"در مورد","examples":[{"de":"Die Fahrt dauert etwa zwei Stunden.","en":"The trip takes about two hours.","ru":"Поездка занимает примерно два часа.","vi":"Cuộc hành trình mất khoảng hai giờ.","fa":"سفر تقریبا دو ساعت طول می کشد."},{"de":"Er wiegt etwa achtzig Kilo.","en":"He weighs about eighty kilos.","ru":"Он весит примерно восемьдесят килограммов.","vi":"Anh ta nặng khoảng tám mươi kg.","fa":"او حدود هشتاد کیلو وزن دارد."}]},{"word":"etwas","en":"something; a little, somewhat","ru":"что-то; немного","vi":"cái gì đó","fa":"چیزی","examples":[{"de":"Möchtest du etwas trinken?","en":"Would you like something to drink?","ru":"Хочешь что-нибудь выпить?","vi":"Bạn có muốn uống gì không?","fa":"آیا می خواهید چیزی بنوشید؟"},{"de":"Ich bin heute etwas müde.","en":"I am somewhat tired today.","ru":"Сегодня я немного устал.","vi":"Hôm nay tôi hơi mệt.","fa":"امروز کمی خسته ام."}]},{"word":"etwas auf die lange Bank schieben","en":"to put something off / procrastinate","ru":"откладывать что-то в долгий ящик","vi":"trì hoãn/ trì hoãn việc gì đó","fa":"به تعویق انداختن چیزی / به تعویق انداختن","examples":[{"de":"Schieb die Steuererklärung nicht auf die lange Bank.","en":"Don't put off the tax return.","ru":"Не откладывай налоговую декларацию в долгий ящик.","vi":"Đừng trì hoãn tờ khai thuế của bạn.","fa":"اظهارنامه مالیاتی خود را به تعویق نیندازید"}]},{"word":"die Eule","en":"owl","ru":"сова","vi":"con cú","fa":"the owl","examples":[{"de":"Die Eule jagt vor allem nachts.","en":"The owl hunts mainly at night.","ru":"Сова охотится в основном ночью.","vi":"Cú săn mồi chủ yếu vào ban đêm.","fa":"جغد عمدتاً در شب شکار می کند."},{"de":"Im Wald hörten wir eine Eule rufen.","en":"In the forest we heard an owl calling.","ru":"В лесу мы услышали, как кричит сова.","vi":"Chúng tôi nghe thấy tiếng cú kêu trong rừng.","fa":"صدای جغدی را در جنگل شنیدیم."},{"de":"Eine Eule kann ihren Kopf sehr weit drehen.","en":"An owl can turn its head very far.","ru":"Сова может очень далеко поворачивать голову.","vi":"Cú có thể quay đầu rất xa.","fa":"جغد می تواند سرش را خیلی دور بچرخاند."}]},{"word":"eventuell","en":"possibly, perhaps","ru":"возможно, при случае","vi":"có thể","fa":"احتمالا","examples":[{"de":"Wir kommen eventuell etwas später.","en":"We might come a bit later.","ru":"Возможно, мы придём немного позже.","vi":"Chúng tôi có thể đến muộn hơn một chút.","fa":"شاید کمی دیرتر بیاییم"},{"de":"Eventuell brauchen wir noch einen zweiten Termin.","en":"We might possibly need a second appointment.","ru":"Возможно, нам понадобится ещё одна встреча.","vi":"Chúng ta có thể cần một cuộc hẹn thứ hai.","fa":"ممکن است به قرار دوم نیاز داشته باشیم."}]},{"word":"ewig","en":"eternal; (colloq.) forever, ages","ru":"вечный; (разг.) целую вечность","vi":"mãi mãi","fa":"برای همیشه","examples":[{"de":"Nichts ist ewig, alles verändert sich.","en":"Nothing is eternal, everything changes.","ru":"Ничто не вечно, всё меняется.","vi":"Không có gì tồn tại mãi mãi, mọi thứ đều thay đổi.","fa":"هیچ چیز برای همیشه ماندگار نیست، همه چیز تغییر می کند."},{"de":"Ich habe ewig auf den Bus gewartet.","en":"I waited an eternity for the bus.","ru":"Я целую вечность ждал автобус.","vi":"Tôi đợi xe buýt mãi mãi.","fa":"برای همیشه منتظر اتوبوس بودم."}]},{"word":"der Experte","en":"expert","ru":"эксперт","vi":"chuyên gia","fa":"کارشناس","examples":[{"de":"Ein Experte hat uns bei der Reparatur geholfen.","en":"An expert helped us with the repair.","ru":"Эксперт помог нам с ремонтом.","vi":"Một chuyên gia đã giúp chúng tôi sửa chữa.","fa":"یک متخصص در تعمیر به ما کمک کرد."},{"de":"Sie ist Expertin für erneuerbare Energien.","en":"She is an expert in renewable energy.","ru":"Она эксперт по возобновляемой энергии.","vi":"Cô ấy là chuyên gia về năng lượng tái tạo.","fa":"او متخصص انرژی های تجدیدپذیر است."}]},{"word":"der Export","en":"export","ru":"экспорт","vi":"xuất khẩu","fa":"صادرات","examples":[{"de":"Der Export von Autos ist wichtig für die Wirtschaft.","en":"The export of cars is important for the economy.","ru":"Экспорт автомобилей важен для экономики.","vi":"Việc xuất khẩu ô tô có ý nghĩa quan trọng đối với nền kinh tế.","fa":"صادرات خودرو برای اقتصاد مهم است."},{"de":"Die Firma lebt hauptsächlich vom Export.","en":"The company lives mainly on exports.","ru":"Компания живёт главным образом за счёт экспорта.","vi":"Công ty sống chủ yếu nhờ xuất khẩu.","fa":"این شرکت عمدتاً از طریق صادرات زندگی می کند."}]},{"word":"extra","en":"extra; specially, especially","ru":"дополнительно; специально","vi":"thêm","fa":"اضافی","examples":[{"de":"Ich habe die Karten extra für dich reserviert.","en":"I reserved the tickets especially for you.","ru":"Я забронировал билеты специально для тебя.","vi":"Tôi đã đặt vé đặc biệt cho bạn.","fa":"من بلیط ها را مخصوص شما رزرو کرده ام."},{"de":"Für das Gepäck muss man extra bezahlen.","en":"You have to pay extra for the luggage.","ru":"За багаж нужно платить дополнительно.","vi":"Bạn phải trả thêm tiền cho hành lý.","fa":"برای چمدان باید هزینه اضافی پرداخت کنید."}]},{"word":"extrem","en":"extreme","ru":"экстремальный, крайний","vi":"cực đoan","fa":"افراطی","examples":[{"de":"Die Hitze war diesen Sommer extrem.","en":"The heat was extreme this summer.","ru":"Жара этим летом была экстремальной.","vi":"Mùa hè năm nay nắng nóng cực độ.","fa":"تابستان امسال گرما شدید بود."},{"de":"Das war eine extrem schwierige Prüfung.","en":"That was an extremely difficult exam.","ru":"Это был крайне сложный экзамен.","vi":"Đây là một bài kiểm tra cực kỳ khó khăn.","fa":"این یک آزمون فوق العاده سخت بود."}]},{"word":"die Fabrik","en":"factory","ru":"фабрика, завод","vi":"nhà máy","fa":"کارخانه","examples":[{"de":"Mein Vater arbeitet in einer Fabrik.","en":"My father works in a factory.","ru":"Мой отец работает на заводе.","vi":"Bố tôi làm việc ở một nhà máy.","fa":"پدرم در یک کارخانه کار می کند."},{"de":"Die Fabrik produziert täglich tausend Autos.","en":"The factory produces a thousand cars daily.","ru":"Завод производит тысячу автомобилей в день.","vi":"Nhà máy sản xuất hàng nghìn chiếc ô tô mỗi ngày.","fa":"این کارخانه روزانه هزار خودرو تولید می کند."}]},{"word":"das Fach","en":"subject (school/academic); compartment","ru":"предмет (учебный); отделение (полки, шкафа)","vi":"chủ đề","fa":"موضوع","examples":[{"de":"Mathematik ist mein Lieblingsfach.","en":"Math is my favorite subject.","ru":"Математика — мой любимый предмет.","vi":"Toán học là môn học yêu thích của tôi.","fa":"ریاضی درس مورد علاقه من است."},{"de":"Leg die Dokumente in das obere Fach.","en":"Put the documents in the top compartment.","ru":"Положи документы в верхнее отделение.","vi":"Đặt tài liệu vào ngăn trên cùng.","fa":"اسناد را در محفظه بالایی قرار دهید."}]},{"word":"die Fachfrau","en":"female expert, specialist (woman)","ru":"специалистка, знаток (женщина)","vi":"chuyên gia","fa":"متخصص","examples":[{"de":"Sie ist eine Fachfrau für erneuerbare Energien.","en":"She is a specialist in renewable energy.","ru":"Она специалистка по возобновляемой энергии.","vi":"Cô ấy là một chuyên gia về năng lượng tái tạo.","fa":"او متخصص انرژی های تجدیدپذیر است."},{"de":"Als Fachfrau kennt sie alle technischen Details.","en":"As a specialist she knows all the technical details.","ru":"Как специалистка она знает все технические детали.","vi":"Là một chuyên gia, cô ấy biết tất cả các chi tiết kỹ thuật.","fa":"او به عنوان یک متخصص، تمام جزئیات فنی را می داند."},{"de":"Wir suchen eine Fachfrau für die Buchhaltung.","en":"We are looking for a specialist for the accounting.","ru":"Мы ищем специалистку по бухгалтерии.","vi":"Chúng tôi đang tìm kiếm một chuyên gia kế toán.","fa":"به دنبال کارشناس حسابداری هستیم."}]},{"word":"die Fachleute","en":"experts, specialists (plural)","ru":"специалисты, эксперты (мн. ч.)","vi":"các chuyên gia","fa":"the professionals","examples":[{"de":"Die Fachleute prüften das Gebäude genau.","en":"The experts inspected the building carefully.","ru":"Специалисты тщательно проверили здание.","vi":"Các chuyên gia đã kiểm tra tòa nhà một cách cẩn thận.","fa":"کارشناسان ساختمان را به دقت بررسی کردند."},{"de":"Für diese Arbeit brauchen wir Fachleute.","en":"For this work we need specialists.","ru":"Для этой работы нам нужны специалисты.","vi":"Chúng tôi cần các chuyên gia cho công việc này.","fa":"برای این کار به افراد متخصص نیازمندیم."},{"de":"Die Fachleute empfehlen regelmäßige Wartung.","en":"The experts recommend regular maintenance.","ru":"Специалисты рекомендуют регулярное техобслуживание.","vi":"Các chuyên gia khuyên bạn nên bảo trì thường xuyên.","fa":"متخصصان تعمیر و نگهداری منظم را توصیه می کنند."}]},{"word":"der Fachmann","en":"expert, specialist (man)","ru":"специалист, знаток (мужчина)","vi":"chuyên gia","fa":"کارشناس","examples":[{"de":"Der Fachmann reparierte die Heizung in einer Stunde.","en":"The specialist repaired the heating in an hour.","ru":"Специалист починил отопление за час.","vi":"Chuyên gia sửa chữa máy sưởi trong một giờ.","fa":"متخصص بخاری را در یک ساعت تعمیر کرد."},{"de":"Bei solchen Fragen sollte man einen Fachmann fragen.","en":"With such questions you should ask a specialist.","ru":"С такими вопросами лучше обратиться к специалисту.","vi":"Nếu bạn có những câu hỏi như thế này, bạn nên hỏi một chuyên gia.","fa":"اگر چنین سوالی دارید، باید از یک متخصص بپرسید."},{"de":"Er gilt als Fachmann auf dem Gebiet der Medizin.","en":"He is regarded as an expert in the field of medicine.","ru":"Он считается знатоком в области медицины.","vi":"Ông được coi là một chuyên gia trong lĩnh vực y học.","fa":"او را متخصص در رشته پزشکی می دانند."}]},{"word":"die Fähigkeit","en":"ability, skill","ru":"способность, умение","vi":"khả năng","fa":"توانایی","examples":[{"de":"Er hat die Fähigkeit, Probleme schnell zu lösen.","en":"He has the ability to solve problems quickly.","ru":"У него есть способность быстро решать проблемы.","vi":"Anh ấy có khả năng giải quyết vấn đề nhanh chóng.","fa":"او توانایی حل سریع مشکلات را دارد."},{"de":"Sprachliche Fähigkeiten sind im Beruf wichtig.","en":"Language skills are important in the profession.","ru":"Языковые способности важны в профессии.","vi":"Kỹ năng ngôn ngữ rất quan trọng trong công việc.","fa":"مهارت زبان در کار مهم است."}]},{"word":"die Fähigkeiten","en":"abilities; skills","ru":"способности; навыки","vi":"các kỹ năng","fa":"مهارت ها","examples":[{"de":"Sie hat die Fähigkeiten, ein Team zu leiten.","en":"She has the skills to lead a team.","ru":"У неё есть способности руководить командой.","vi":"Cô ấy có kỹ năng lãnh đạo một nhóm.","fa":"او مهارت رهبری یک تیم را دارد."},{"de":"Im Kurs entwickeln die Kinder neue Fähigkeiten.","en":"In the course the children develop new skills.","ru":"На курсе дети развивают новые навыки.","vi":"Trong suốt khóa học, trẻ em được phát triển các kỹ năng mới.","fa":"در طول دوره، کودکان مهارت های جدیدی را توسعه می دهند."}]},{"word":"die Fahrbahn","en":"carriageway, road lane","ru":"проезжая часть, полоса движения","vi":"con đường","fa":"the roadway","examples":[{"de":"Auf der nassen Fahrbahn muss man langsam fahren.","en":"On the wet carriageway you have to drive slowly.","ru":"На мокрой проезжей части нужно ехать медленно.","vi":"Bạn phải lái xe chậm trên con đường ướt.","fa":"در جاده خیس باید آهسته رانندگی کنید."},{"de":"Die Fahrbahn war wegen des Unfalls gesperrt.","en":"The carriageway was closed because of the accident.","ru":"Проезжая часть была перекрыта из-за аварии.","vi":"Con đường bị đóng cửa do vụ tai nạn.","fa":"به دلیل تصادف جاده بسته شد."},{"de":"Ein Tier lief plötzlich über die Fahrbahn.","en":"An animal suddenly ran across the road.","ru":"Животное вдруг выбежало на проезжую часть.","vi":"Một con vật bất ngờ chạy qua đường.","fa":"حیوانی ناگهان از جاده عبور کرد."}]},{"word":"fahren","en":"to drive; to go (by vehicle)","ru":"ехать, водить","vi":"lái xe","fa":"رانندگی کنید","examples":[{"de":"Wir fahren morgen mit dem Auto nach Berlin.","en":"Tomorrow we are driving to Berlin by car.","ru":"Завтра мы едем на машине в Берлин.","vi":"Ngày mai chúng ta sẽ đi Berlin bằng ô tô.","fa":"فردا با ماشین میریم برلین."},{"de":"Kannst du Fahrrad fahren?","en":"Can you ride a bike?","ru":"Ты умеешь кататься на велосипеде?","vi":"Bạn có thể đi xe đạp không?","fa":"آیا می توانی دوچرخه سواری کنی؟"}]},{"word":"die Fahrertür","en":"driver's door","ru":"водительская дверь","vi":"cửa tài xế","fa":"the driver's door","examples":[{"de":"Die Fahrertür lässt sich nicht mehr richtig öffnen.","en":"The driver's door can no longer be opened properly.","ru":"Водительская дверь больше не открывается как следует.","vi":"Cửa tài xế không thể mở được nữa.","fa":"درب راننده دیگر نمی تواند به درستی باز شود."},{"de":"Er stieg durch die Fahrertür ins Auto.","en":"He got into the car through the driver's door.","ru":"Он сел в машину через водительскую дверь.","vi":"Anh ta bước vào xe qua cửa tài xế.","fa":"از در راننده سوار ماشین شد."},{"de":"An der Fahrertür war ein kleiner Kratzer.","en":"There was a small scratch on the driver's door.","ru":"На водительской двери была небольшая царапина.","vi":"Có một vết xước nhỏ trên cửa tài xế.","fa":"یک خراش کوچک روی در راننده بود."}]},{"word":"die Fahrkarte","en":"(travel) ticket","ru":"проездной билет","vi":"vé","fa":"بلیط","examples":[{"de":"Ich habe meine Fahrkarte für den Zug schon online gekauft.","en":"I already bought my train ticket online.","ru":"Я уже купил билет на поезд онлайн.","vi":"Tôi đã mua vé tàu trực tuyến rồi.","fa":"من قبلا بلیط قطارم را آنلاین خریده ام."},{"de":"Ohne gültige Fahrkarte darf man nicht in den Zug einsteigen.","en":"You are not allowed to board the train without a valid ticket.","ru":"Без действующего билета нельзя садиться в поезд.","vi":"Bạn không được phép lên tàu nếu không có vé hợp lệ.","fa":"بدون بلیط معتبر اجازه سوار شدن به قطار را ندارید."}]},{"word":"das Fahrrad","en":"bicycle","ru":"велосипед","vi":"chiếc xe đạp","fa":"دوچرخه","examples":[{"de":"Ich fahre jeden Tag mit dem Fahrrad zur Arbeit.","en":"I ride my bicycle to work every day.","ru":"Я каждый день езжу на работу на велосипеде.","vi":"Tôi đạp xe đi làm hàng ngày.","fa":"من هر روز با دوچرخه به سر کار می روم."},{"de":"Sein Fahrrad wurde letzte Woche gestohlen.","en":"His bicycle was stolen last week.","ru":"Его велосипед украли на прошлой неделе.","vi":"Xe đạp của anh ấy đã bị đánh cắp vào tuần trước.","fa":"دوچرخه او هفته گذشته دزدیده شد."}]},{"word":"das Fahrzeug","en":"vehicle","ru":"транспортное средство","vi":"chiếc xe","fa":"وسیله نقلیه","examples":[{"de":"Das Fahrzeug muss regelmäßig zur Inspektion.","en":"The vehicle has to go for inspection regularly.","ru":"Транспортное средство должно регулярно проходить техосмотр.","vi":"Xe phải được kiểm tra thường xuyên.","fa":"خودرو باید مرتباً بازرسی شود."},{"de":"Auf der Straße standen viele Fahrzeuge im Stau.","en":"Many vehicles were stuck in the traffic jam on the road.","ru":"На дороге в пробке стояло много машин.","vi":"Trên đường có rất nhiều phương tiện bị mắc kẹt khi tham gia giao thông.","fa":"خودروهای زیادی در جاده گیر کرده بودند."},{"de":"Dieses Fahrzeug ist sehr sparsam im Verbrauch.","en":"This vehicle is very economical in its consumption.","ru":"Это транспортное средство очень экономично в расходе.","vi":"Xe này rất tiết kiệm nhiên liệu.","fa":"این خودرو بسیار کم مصرف است."}]},{"word":"fair","en":"fair","ru":"честный, справедливый","vi":"công bằng","fa":"منصفانه","examples":[{"de":"Der Schiedsrichter hat fair entschieden.","en":"The referee made a fair decision.","ru":"Судья принял справедливое решение.","vi":"Trọng tài đã đưa ra quyết định công bằng.","fa":"داور تصمیم عادلانه ای گرفت."},{"de":"Wir sollten alle Mitarbeiter fair behandeln.","en":"We should treat all employees fairly.","ru":"Мы должны справедливо относиться ко всем сотрудникам.","vi":"Chúng ta nên đối xử công bằng với tất cả nhân viên.","fa":"ما باید با همه کارمندان منصفانه رفتار کنیم."}]},{"word":"der Faktor","en":"factor","ru":"фактор","vi":"yếu tố","fa":"عامل","examples":[{"de":"Zeit ist bei diesem Projekt ein wichtiger Faktor.","en":"Time is an important factor in this project.","ru":"Время — важный фактор в этом проекте.","vi":"Thời gian là một yếu tố quan trọng trong dự án này.","fa":"زمان عامل مهمی در این پروژه است."},{"de":"Gesunde Ernährung ist ein entscheidender Faktor für das Wohlbefinden.","en":"Healthy eating is a decisive factor for well-being.","ru":"Здоровое питание — решающий фактор для самочувствия.","vi":"Dinh dưỡng lành mạnh là yếu tố quan trọng để có được sức khỏe tốt.","fa":"تغذیه سالم عامل مهمی برای تندرستی است."}]},{"word":"der Fall","en":"case","ru":"случай","vi":"trường hợp","fa":"مورد","examples":[{"de":"In diesem Fall hast du recht.","en":"In this case you are right.","ru":"В этом случае ты прав.","vi":"Trong trường hợp này bạn đúng.","fa":"در این مورد حق با شماست."},{"de":"Der Polizist untersucht den Fall genau.","en":"The police officer is investigating the case closely.","ru":"Полицейский тщательно расследует это дело.","vi":"Cảnh sát đang điều tra vụ án chặt chẽ.","fa":"افسر پلیس این پرونده را از نزدیک بررسی می کند."}]},{"word":"fallen","en":"to fall","ru":"падать","vi":"ngã","fa":"سقوط","examples":[{"de":"Das Glas ist vom Tisch gefallen und zerbrochen.","en":"The glass fell off the table and broke.","ru":"Стакан упал со стола и разбился.","vi":"Chiếc ly rơi khỏi bàn và vỡ tan.","fa":"لیوان از روی میز افتاد و شکست."},{"de":"Im Herbst fallen die Blätter von den Bäumen.","en":"In autumn the leaves fall from the trees.","ru":"Осенью листья падают с деревьев.","vi":"Vào mùa thu, lá rụng khỏi cây.","fa":"در پاییز برگها از درختان می ریزند."}]},{"word":"fällig","en":"due (payment, date)","ru":"подлежащий оплате, наступивший срок","vi":"đến hạn","fa":"به دلیل","examples":[{"de":"Die Miete ist am Ersten des Monats fällig.","en":"The rent is due on the first of the month.","ru":"Арендная плата подлежит оплате первого числа месяца.","vi":"Tiền thuê nhà phải trả vào ngày đầu tiên của tháng.","fa":"پرداخت اجاره اول ماه می باشد."},{"de":"Die Rechnung ist bereits seit zwei Wochen fällig.","en":"The invoice has already been due for two weeks.","ru":"Счёт должен быть оплачен уже две недели.","vi":"Hóa đơn đã đến hạn thanh toán được hai tuần.","fa":"این لایحه در حال حاضر به مدت دو هفته سررسید شده است."}]},{"word":"falls","en":"in case, if","ru":"если, в случае если","vi":"nếu","fa":"اگر","examples":[{"de":"Falls es regnet, bleiben wir zu Hause.","en":"In case it rains, we'll stay home.","ru":"Если пойдёт дождь, мы останемся дома.","vi":"Nếu trời mưa thì chúng ta ở nhà.","fa":"اگر باران ببارد، ما در خانه می مانیم."},{"de":"Ruf mich an, falls du Hilfe brauchst.","en":"Call me if you need help.","ru":"Позвони мне, если тебе понадобится помощь.","vi":"Hãy gọi cho tôi nếu bạn cần giúp đỡ.","fa":"اگر به کمک نیاز دارید با من تماس بگیرید."}]},{"word":"falsch","en":"wrong, false, incorrect","ru":"неправильный, ложный","vi":"sai","fa":"اشتباه","examples":[{"de":"Diese Antwort ist leider falsch.","en":"Unfortunately, this answer is wrong.","ru":"К сожалению, этот ответ неправильный.","vi":"Thật không may, câu trả lời này là sai.","fa":"متاسفانه این پاسخ اشتباه است."},{"de":"Er hat die falsche Nummer gewählt.","en":"He dialed the wrong number.","ru":"Он набрал неправильный номер.","vi":"Anh gọi nhầm số rồi.","fa":"او شماره را اشتباه گرفت."}]},{"word":"die Familie","en":"family","ru":"семья","vi":"gia đình","fa":"خانواده","examples":[{"de":"Meine Familie ist mir sehr wichtig.","en":"My family is very important to me.","ru":"Моя семья очень важна для меня.","vi":"Gia đình tôi rất quan trọng với tôi.","fa":"خانواده ام برایم خیلی مهم است."},{"de":"Wir verbringen Weihnachten immer mit der ganzen Familie.","en":"We always spend Christmas with the whole family.","ru":"Рождество мы всегда проводим со всей семьёй.","vi":"Chúng tôi luôn đón Giáng sinh cùng cả gia đình.","fa":"ما همیشه کریسمس را با تمام خانواده می گذرانیم."}]},{"word":"das Familienleben","en":"family life","ru":"семейная жизнь","vi":"cuộc sống gia đình","fa":"زندگی خانوادگی","examples":[{"de":"Ein harmonisches Familienleben ist ihr sehr wichtig.","en":"A harmonious family life is very important to her.","ru":"Гармоничная семейная жизнь очень важна для неё.","vi":"Đối với cô, cuộc sống gia đình hòa thuận là rất quan trọng.","fa":"زندگی خانوادگی هماهنگ برای او بسیار مهم است."},{"de":"Die Arbeit lässt ihm kaum Zeit für das Familienleben.","en":"Work leaves him hardly any time for family life.","ru":"Работа почти не оставляет ему времени на семейную жизнь.","vi":"Công việc khiến anh có ít thời gian dành cho cuộc sống gia đình.","fa":"کار زمان کمی را برای زندگی خانوادگی در اختیار او می گذارد."},{"de":"Das Familienleben hat sich seit der Geburt verändert.","en":"Family life has changed since the birth.","ru":"Семейная жизнь изменилась после рождения ребёнка.","vi":"Cuộc sống gia đình đã thay đổi kể từ khi sinh ra.","fa":"زندگی خانوادگی از بدو تولد تغییر کرده است."}]},{"word":"das Familienmitglied","en":"family member","ru":"член семьи","vi":"thành viên gia đình","fa":"عضو خانواده","examples":[{"de":"Zu Weihnachten kommen alle Familienmitglieder zusammen.","en":"At Christmas all the family members come together.","ru":"На Рождество собираются все члены семьи.","vi":"Vào dịp Giáng sinh, tất cả các thành viên trong gia đình đều quây quần bên nhau.","fa":"در کریسمس همه اعضای خانواده دور هم جمع می شوند."},{"de":"Jedes Familienmitglied hat eine eigene Aufgabe im Haushalt.","en":"Each family member has their own task in the household.","ru":"У каждого члена семьи своя обязанность по дому.","vi":"Mỗi thành viên trong gia đình đều có vai trò riêng của mình trong gia đình.","fa":"هر یک از اعضای خانواده نقش خود را در خانواده دارند."},{"de":"Ein neues Familienmitglied wurde letzte Woche geboren.","en":"A new family member was born last week.","ru":"На прошлой неделе родился новый член семьи.","vi":"Một thành viên mới trong gia đình đã chào đời vào tuần trước.","fa":"هفته گذشته یکی از اعضای خانواده جدید متولد شد."}]},{"word":"der Familienstand","en":"marital status","ru":"семейное положение","vi":"tình trạng hôn nhân","fa":"وضعیت تاهل","examples":[{"de":"Bitte geben Sie Ihren Familienstand im Formular an.","en":"Please state your marital status on the form.","ru":"Пожалуйста, укажите ваше семейное положение в анкете.","vi":"Vui lòng cho biết tình trạng hôn nhân của bạn trong mẫu đơn.","fa":"لطفا وضعیت تاهل خود را در فرم ذکر کنید."},{"de":"Ihr Familienstand hat sich nach der Hochzeit geändert.","en":"Her marital status changed after the wedding.","ru":"Её семейное положение изменилось после свадьбы.","vi":"Tình trạng hôn nhân của cô thay đổi sau đám cưới.","fa":"وضعیت تاهل او بعد از عروسی تغییر کرد."}]},{"word":"der Fan","en":"fan, supporter","ru":"фанат, болельщик, поклонник","vi":"cái quạt","fa":"فن","examples":[{"de":"Er ist ein großer Fan dieser Band.","en":"He is a big fan of this band.","ru":"Он большой фанат этой группы.","vi":"Anh ấy là một fan hâm mộ lớn của ban nhạc này.","fa":"او از طرفداران پر و پا قرص این گروه است."},{"de":"Die Fans jubelten dem Sieger zu.","en":"The fans cheered the winner.","ru":"Болельщики приветствовали победителя.","vi":"Người hâm mộ cổ vũ cho người chiến thắng.","fa":"هواداران برنده را تشویق کردند."},{"de":"Als Fan besucht sie jedes Heimspiel.","en":"As a supporter she attends every home game.","ru":"Как болельщица она ходит на каждый домашний матч.","vi":"Là một người hâm mộ, cô ấy tham dự mọi trận đấu trên sân nhà.","fa":"او به عنوان یک هوادار در هر بازی خانگی حضور دارد."}]},{"word":"fangen","en":"to catch","ru":"ловить","vi":"bắt","fa":"گرفتن","examples":[{"de":"Der Hund konnte den Ball gut fangen.","en":"The dog could catch the ball well.","ru":"Собака хорошо ловила мяч.","vi":"Con chó đã có thể bắt bóng tốt.","fa":"سگ به خوبی توانست توپ را بگیرد."},{"de":"Die Kinder spielen im Garten Fangen.","en":"The children are playing tag in the garden.","ru":"Дети играют в саду в салки.","vi":"Bọn trẻ đang chơi đuổi bắt trong vườn.","fa":"بچه ها در باغ مشغول بازی گرفتن هستند."}]},{"word":"die Fantasie","en":"imagination, fantasy","ru":"фантазия, воображение","vi":"sự tưởng tượng","fa":"the fantasy","examples":[{"de":"Kinder haben oft eine lebhafte Fantasie.","en":"Children often have a vivid imagination.","ru":"У детей часто живое воображение.","vi":"Trẻ em thường có trí tưởng tượng sống động.","fa":"کودکان اغلب تخیل روشنی دارند."},{"de":"Mit etwas Fantasie kann man viel erreichen.","en":"With a bit of imagination you can achieve a lot.","ru":"Немного фантазии — и можно многого добиться.","vi":"Với một chút trí tưởng tượng, bạn có thể đạt được rất nhiều điều.","fa":"با کمی تخیل می توانید به چیزهای زیادی دست پیدا کنید."},{"de":"Seine Geschichten zeigen viel Fantasie.","en":"His stories show a lot of imagination.","ru":"Его рассказы полны фантазии.","vi":"Những câu chuyện của anh ấy thể hiện rất nhiều trí tưởng tượng.","fa":"داستان های او تخیل زیادی را نشان می دهد."}]},{"word":"die Fantasie/Phantasie","en":"imagination","ru":"воображение, фантазия","vi":"sự tưởng tượng/tưởng tượng","fa":"فانتزی / فانتزی","examples":[{"de":"Kinder haben oft eine sehr lebendige Fantasie.","en":"Children often have a very vivid imagination.","ru":"У детей часто очень живое воображение.","vi":"Trẻ em thường có trí tưởng tượng rất sống động.","fa":"کودکان اغلب تخیل بسیار روشنی دارند."},{"de":"Mit ein bisschen Fantasie kann man aus alten Möbeln etwas Neues machen.","en":"With a bit of imagination you can make something new out of old furniture.","ru":"С небольшой фантазией можно сделать из старой мебели что-то новое.","vi":"Với một chút trí tưởng tượng, bạn có thể biến đồ cũ thành đồ mới.","fa":"With a little imagination you can turn old furniture into something new."}]},{"word":"die Farbe","en":"color","ru":"цвет","vi":"màu sắc","fa":"رنگ","examples":[{"de":"Welche Farbe gefällt dir am besten?","en":"Which color do you like best?","ru":"Какой цвет тебе нравится больше всего?","vi":"Bạn thích màu nào nhất?","fa":"کدام رنگ را بیشتر دوست دارید؟"},{"de":"Wir haben die Wand in einer hellen Farbe gestrichen.","en":"We painted the wall in a light color.","ru":"Мы покрасили стену в светлый цвет.","vi":"Chúng tôi sơn tường màu sáng.","fa":"دیوار را با رنگ روشن رنگ کردیم."}]},{"word":"farbig","en":"coloured, colourful, in colour","ru":"цветной, разноцветный, в цвете","vi":"màu","fa":"رنگی","examples":[{"de":"Bitte drucken Sie das Foto farbig aus.","en":"Please print the photo in colour.","ru":"Напечатай, пожалуйста, фотографию в цвете.","vi":"Vui lòng in ảnh màu.","fa":"لطفا عکس را رنگی چاپ کنید."},{"de":"Sie trägt gern farbige Kleidung.","en":"She likes to wear colourful clothing.","ru":"Она любит носить яркую одежду.","vi":"Cô ấy thích mặc quần áo màu.","fa":"او دوست دارد لباس های رنگی بپوشد."},{"de":"Das Buch enthält viele farbige Abbildungen.","en":"The book contains many colour illustrations.","ru":"В книге много цветных иллюстраций.","vi":"Sách có nhiều hình minh họa đầy màu sắc.","fa":"این کتاب شامل بسیاری از تصاویر رنگی است."}]},{"word":"färbig","en":"coloured (Austrian/Swiss variant of farbig)","ru":"цветной (австр./швейц. вариант farbig)","vi":"màu","fa":"رنگی","examples":[{"de":"Sie malte das Bild mit färbigen Stiften.","en":"She drew the picture with coloured pencils.","ru":"Она нарисовала картинку цветными карандашами.","vi":"Cô ấy vẽ bức tranh bằng bút chì màu.","fa":"او تصویر را با مداد رنگی کشید."},{"de":"Auf dem Tisch lagen viele färbige Blätter.","en":"There were many coloured sheets of paper on the table.","ru":"На столе лежало много цветных листов бумаги.","vi":"Trên bàn có rất nhiều chiếc lá đủ màu sắc.","fa":"برگ های رنگی زیادی روی میز بود."},{"de":"Das Kind trug eine färbige Mütze.","en":"The child wore a colourful hat.","ru":"Ребёнок был в разноцветной шапке.","vi":"Đứa trẻ đội một chiếc mũ màu.","fa":"کودک کلاه رنگی بر سر داشت."}]},{"word":"das Faschierte","en":"minced meat","ru":"фарш","vi":"sự băm nhỏ","fa":"چرخ شده","examples":[{"de":"Für die Soße brauchen wir ein halbes Kilo Faschiertes.","en":"For the sauce we need half a kilo of minced meat.","ru":"Для соуса нам нужно полкило фарша.","vi":"Đối với nước sốt chúng ta cần nửa kg thịt băm.","fa":"برای سس به نیم کیلو گوشت چرخ کرده نیاز داریم."},{"de":"Meine Oma macht die besten Laibchen aus Faschiertem.","en":"My grandma makes the best patties from minced meat.","ru":"Моя бабушка делает лучшие котлеты из фарша.","vi":"Bà tôi làm món chả thịt bằm ngon nhất.","fa":"مادربزرگ من بهترین قیمه های گوشت چرخ کرده را درست می کند."}]},{"word":"der Fasching","en":"carnival","ru":"карнавал","vi":"lễ hội","fa":"کارناوال","examples":[{"de":"Zu Fasching verkleiden sich die Kinder als Prinzessin oder Pirat.","en":"At carnival the children dress up as a princess or a pirate.","ru":"На карнавал дети наряжаются принцессами или пиратами.","vi":"Đối với lễ hội hóa trang, trẻ em hóa trang thành công chúa hoặc cướp biển.","fa":"برای کارناوال، بچه ها لباس پرنسس یا دزد دریایی می پوشند."},{"de":"In Köln wird der Fasching besonders groß gefeiert.","en":"In Cologne, carnival is celebrated on an especially large scale.","ru":"В Кёльне карнавал отмечают особенно масштабно.","vi":"Lễ hội hóa trang được tổ chức đặc biệt ở Cologne.","fa":"کارناوال به ویژه در کلن جشن گرفته می شود."}]},{"word":"die Fasnacht","en":"carnival","ru":"карнавал","vi":"lễ hội","fa":"کارناوال","examples":[{"de":"In Basel beginnt die Fasnacht traditionell um vier Uhr morgens.","en":"In Basel, carnival traditionally begins at four in the morning.","ru":"В Базеле карнавал традиционно начинается в четыре утра.","vi":"Ở Basel, Fasnacht theo truyền thống bắt đầu lúc bốn giờ sáng.","fa":"در بازل، Fasnacht به طور سنتی در ساعت چهار صبح آغاز می شود."},{"de":"Während der Fasnacht ziehen bunte Umzüge durch die Stadt.","en":"During carnival, colorful parades move through the city.","ru":"Во время карнавала по городу проходят пёстрые шествия.","vi":"Trong lễ hội hóa trang, các cuộc diễu hành đầy màu sắc di chuyển khắp thành phố.","fa":"در طول کارناوال، رژه های رنگارنگ در شهر حرکت می کنند."}]},{"word":"fassen","en":"to grasp; to hold","ru":"хватать, схватить","vi":"nắm bắt","fa":"درک کردن","examples":[{"de":"Er fasste das Kind an der Hand, bevor sie die Straße überquerten.","en":"He grabbed the child's hand before they crossed the street.","ru":"Он взял ребёнка за руку, прежде чем они перешли улицу.","vi":"Anh nắm lấy tay đứa trẻ trước khi họ băng qua đường.","fa":"دست کودک را قبل از عبور از خیابان گرفت."},{"de":"Ich kann es kaum fassen, dass wir schon fertig sind.","en":"I can hardly grasp that we're already finished.","ru":"Я едва могу поверить, что мы уже закончили.","vi":"Tôi không thể tin được là chúng ta đã xong việc.","fa":"من نمی توانم باور کنم که ما در حال حاضر تمام شده است."}]},{"word":"fast","en":"almost","ru":"почти","vi":"gần như","fa":"تقریبا","examples":[{"de":"Es ist fast neun Uhr, wir müssen los.","en":"It's almost nine o'clock, we have to go.","ru":"Уже почти девять часов, нам пора идти.","vi":"Đã gần chín giờ rồi, chúng ta phải đi thôi.","fa":"ساعت نزدیک نه است، باید بریم."},{"de":"Ich hätte fast den Bus verpasst.","en":"I almost missed the bus.","ru":"Я чуть не опоздал на автобус.","vi":"Tôi gần như đã lỡ chuyến xe buýt.","fa":"تقریباً اتوبوس را از دست دادم."}]},{"word":"faul","en":"lazy","ru":"ленивый","vi":"lười biếng","fa":"تنبل","examples":[{"de":"Sei nicht so faul und hilf mir beim Aufräumen!","en":"Don't be so lazy and help me tidy up!","ru":"Не будь таким ленивым и помоги мне убраться!","vi":"Đừng lười biếng thế và giúp tôi dọn dẹp nhé!","fa":"اینقدر تنبل نباش و به من کمک کن تمیز کنم!"},{"de":"An Sonntagen bin ich gern ein bisschen faul.","en":"On Sundays I like to be a bit lazy.","ru":"По воскресеньям я люблю немного полениться.","vi":"Tôi thích lười biếng một chút vào ngày chủ nhật.","fa":"من دوست دارم یکشنبه ها کمی تنبل باشم."}]},{"word":"faulenzen","en":"to laze around","ru":"бездельничать","vi":"lười biếng xung quanh","fa":"تنبلی در اطراف","examples":[{"de":"Im Urlaub will ich einfach nur am Strand faulenzen.","en":"On vacation I just want to laze around on the beach.","ru":"В отпуске я хочу просто бездельничать на пляже.","vi":"Khi tôi đi nghỉ, tôi chỉ muốn nằm dài trên bãi biển.","fa":"وقتی در تعطیلات هستم، فقط می خواهم در ساحل استراحت کنم."},{"de":"Statt zu lernen, hat er den ganzen Nachmittag gefaulenzt.","en":"Instead of studying, he lazed around all afternoon.","ru":"Вместо того чтобы учиться, он весь день бездельничал.","vi":"Thay vì học, anh lười biếng suốt buổi chiều.","fa":"به جای درس خواندن، تمام بعدازظهر را تنبلی می کرد."}]},{"word":"der Fauteuil","en":"armchair","ru":"кресло","vi":"chiếc ghế bành","fa":"صندلی راحتی","examples":[{"de":"Nach der Arbeit setzt sich mein Vater immer in seinen Fauteuil.","en":"After work my father always sits down in his armchair.","ru":"После работы мой отец всегда садится в своё кресло.","vi":"Sau giờ làm việc, bố tôi luôn ngồi xuống chiếc ghế bành.","fa":"پدرم بعد از کار همیشه روی صندلی راحتی اش می نشیند."},{"de":"Der alte Fauteuil im Wohnzimmer ist sehr bequem.","en":"The old armchair in the living room is very comfortable.","ru":"Старое кресло в гостиной очень удобное.","vi":"Chiếc ghế bành cũ trong phòng khách rất thoải mái.","fa":"The old armchair in the living room is very comfortable."}]},{"word":"der Feber","en":"February (Austrian)","ru":"февраль (австрийский вариант слова Februar)","vi":"tháng hai","fa":"فوریه","examples":[{"de":"In Österreich heißt der zweite Monat oft Feber.","en":"In Austria the second month is often called Feber.","ru":"В Австрии второй месяц часто называют Feber.","vi":"Ở Áo, tháng thứ hai thường được gọi là tháng Hai.","fa":"در اتریش ماه دوم اغلب فوریه نامیده می شود."},{"de":"Mein Geburtstag ist am zehnten Feber.","en":"My birthday is on the tenth of February.","ru":"Мой день рождения десятого февраля.","vi":"Sinh nhật của tôi là vào ngày mười tháng hai.","fa":"تولد من دهم بهمن است."},{"de":"Im Feber ist es bei uns meistens noch sehr kalt.","en":"In February it is usually still very cold where we live.","ru":"В феврале у нас обычно ещё очень холодно.","vi":"Vào tháng 2 ở đây thường rất lạnh.","fa":"در ماه فوریه اینجا معمولاً بسیار سرد است."}]},{"word":"fegen","en":"to sweep","ru":"мести, подметать","vi":"quét","fa":"جارو کردن","examples":[{"de":"Ich fege jeden Morgen die Küche.","en":"I sweep the kitchen every morning.","ru":"Я каждое утро подметаю кухню.","vi":"Tôi quét nhà bếp vào mỗi buổi sáng.","fa":"من هر روز صبح آشپزخانه را جارو می کنم."},{"de":"Hast du schon den Hof gefegt?","en":"Have you already swept the yard?","ru":"Ты уже подмёл двор?","vi":"Bạn đã quét sân chưa?","fa":"آیا قبلاً حیاط را جارو کرده اید؟"},{"de":"Der Sturm fegte über das Land.","en":"The storm swept across the country.","ru":"Буря пронеслась по стране.","vi":"Cơn bão quét qua đất nước.","fa":"طوفان سراسر کشور را فرا گرفت."}]},{"word":"fehlen","en":"to be missing","ru":"не хватать, отсутствовать","vi":"thiếu; vắng mặt","fa":"غایب بودن؛ کم بودن","examples":[{"de":"In diesem Satz fehlt ein Wort.","en":"A word is missing in this sentence.","ru":"В этом предложении не хватает слова.","vi":"Có một từ còn thiếu trong câu này.","fa":"یک کلمه در این جمله گم شده است."},{"de":"Drei Schüler fehlen heute wegen Krankheit.","en":"Three students are absent today due to illness.","ru":"Трое учеников сегодня отсутствуют по болезни.","vi":"Ba học sinh mất tích hôm nay do bị bệnh.","fa":"سه دانش آموز امروز به دلیل بیماری مفقود شده اند."}]},{"word":"der Fehler","en":"mistake","ru":"ошибка","vi":"lỗi","fa":"خطا","examples":[{"de":"Ich habe im Test nur einen Fehler gemacht.","en":"I only made one mistake in the test.","ru":"Я допустил только одну ошибку в тесте.","vi":"Tôi chỉ mắc một lỗi trong bài kiểm tra.","fa":"من فقط یک اشتباه در آزمون انجام دادم."},{"de":"Es tut mir leid, das war mein Fehler.","en":"I'm sorry, that was my mistake.","ru":"Извини, это была моя ошибка.","vi":"Tôi xin lỗi, đó là lỗi của tôi.","fa":"متاسفم، این اشتباه من بود."}]},{"word":"Feierabend machen","en":"to call it a day (finish work)","ru":"закончить рабочий день","vi":"gọi nó là một ngày","fa":"آن را یک روز بنامیم","examples":[{"de":"Es ist schon spät, lass uns Feierabend machen.","en":"It's already late, let's call it a day.","ru":"Уже поздно, давай заканчивать на сегодня.","vi":"Giờ đã muộn rồi, hãy tạm gọi là một ngày nhé.","fa":"الان دیر شده، بیایید آن را یک روز بنامیم."}]},{"word":"feiern","en":"to celebrate","ru":"праздновать","vi":"ăn mừng","fa":"جشن بگیرید","examples":[{"de":"Wir feiern heute Abend meinen Geburtstag.","en":"We are celebrating my birthday tonight.","ru":"Сегодня вечером мы празднуем мой день рождения.","vi":"Tối nay chúng ta tổ chức sinh nhật cho tôi.","fa":"ما امشب تولدم را جشن می گیریم."},{"de":"Nach der Prüfung wollen wir richtig feiern.","en":"After the exam we want to really celebrate.","ru":"После экзамена мы хотим как следует отпраздновать.","vi":"Sau kỳ thi chúng tôi thực sự muốn ăn mừng.","fa":"بعد از امتحان ما واقعاً می خواهیم جشن بگیریم."}]},{"word":"die Feige","en":"fig","ru":"инжир, фига","vi":"quả sung","fa":"the fig","examples":[{"de":"Im Sommer esse ich gern frische Feigen.","en":"In summer I like to eat fresh figs.","ru":"Летом я люблю есть свежий инжир.","vi":"Vào mùa hè tôi thích ăn quả sung tươi.","fa":"در تابستان من دوست دارم انجیر تازه بخورم."},{"de":"Die Feige ist innen weich und süß.","en":"The fig is soft and sweet inside.","ru":"Внутри инжир мягкий и сладкий.","vi":"Quả sung mềm và ngọt bên trong.","fa":"انجیر از داخل نرم و شیرین است."},{"de":"Im Garten meiner Tante wächst ein großer Feigenbaum.","en":"A big fig tree grows in my aunt's garden.","ru":"В саду у моей тёти растёт большое фиговое дерево.","vi":"Một cây sung lớn mọc trong vườn của dì tôi.","fa":"یک درخت انجیر بزرگ در باغ عمه ام می روید."}]},{"word":"der Feinstaub","en":"particulate matter, fine dust","ru":"мелкодисперсная пыль, взвешенные частицы","vi":"bụi mịn","fa":"گرد و غبار ریز","examples":[{"de":"Der Feinstaub in der Luft ist gefährlich für die Gesundheit.","en":"The particulate matter in the air is dangerous to health.","ru":"Мелкодисперсная пыль в воздухе опасна для здоровья.","vi":"Bụi mịn trong không khí rất nguy hiểm cho sức khỏe.","fa":"گرد و غبار ریز موجود در هوا برای سلامتی خطرناک است."},{"de":"Autos und Heizungen erzeugen viel Feinstaub.","en":"Cars and heating systems produce a lot of fine dust.","ru":"Автомобили и системы отопления создают много мелкой пыли.","vi":"Ô tô và máy sưởi tạo ra rất nhiều bụi mịn.","fa":"ماشین ها و بخاری ها گرد و غبار ریز زیادی تولید می کنند."},{"de":"In der Innenstadt ist die Belastung durch Feinstaub hoch.","en":"In the city centre the level of particulate matter is high.","ru":"В центре города уровень мелкодисперсной пыли высок.","vi":"Ở trung tâm thành phố, tình trạng ô nhiễm do bụi mịn rất cao.","fa":"در مرکز شهر، آلودگی ناشی از ذرات معلق زیاد است."}]},{"word":"das Feld","en":"field","ru":"поле","vi":"cánh đồng","fa":"the field","examples":[{"de":"Die Bauern arbeiten seit dem Morgen auf dem Feld.","en":"The farmers have been working in the field since morning.","ru":"Крестьяне работают в поле с самого утра.","vi":"Những người nông dân đã làm việc trên đồng từ sáng.","fa":"کشاورزان از صبح در مزارع مشغول به کار هستند."},{"de":"Hinter unserem Haus liegt ein großes grünes Feld.","en":"Behind our house there is a large green field.","ru":"За нашим домом находится большое зелёное поле.","vi":"Có một cánh đồng xanh rộng lớn phía sau nhà chúng tôi.","fa":"پشت خانه ما یک زمین سبز بزرگ است."}]},{"word":"das Fenster","en":"window","ru":"окно","vi":"cửa sổ","fa":"پنجره","examples":[{"de":"Kannst du bitte das Fenster öffnen? Es ist so warm hier.","en":"Can you please open the window? It's so warm in here.","ru":"Можешь открыть окно? Здесь так тепло.","vi":"Bạn có thể vui lòng mở cửa sổ được không? Ở đây thật ấm áp.","fa":"میشه لطفا پنجره رو باز کن اینجا خیلی گرمه"},{"de":"Von meinem Fenster aus sehe ich den ganzen Park.","en":"From my window I can see the whole park.","ru":"Из моего окна виден весь парк.","vi":"Từ cửa sổ của tôi, tôi có thể nhìn thấy toàn bộ công viên.","fa":"از پنجره ام می توانم کل پارک را ببینم."}]},{"word":"die Ferien","en":"vacation, holidays","ru":"каникулы","vi":"những ngày nghỉ","fa":"تعطیلات","examples":[{"de":"Endlich beginnen morgen die Sommerferien!","en":"The summer vacation finally starts tomorrow!","ru":"Наконец завтра начинаются летние каникулы!","vi":"Kỳ nghỉ hè cuối cùng cũng bắt đầu vào ngày mai!","fa":"بالاخره از فردا تعطیلات تابستانی شروع می شود!"},{"de":"In den Ferien fahren wir jedes Jahr ans Meer.","en":"During the holidays we go to the sea every year.","ru":"На каникулах мы каждый год ездим на море.","vi":"Chúng tôi đi biển hàng năm vào kỳ nghỉ.","fa":"ما هر سال در تعطیلات به دریا می رویم."}]},{"word":"die Fernbedienung","en":"remote control","ru":"пульт дистанционного управления","vi":"điều khiển từ xa","fa":"کنترل از راه دور","examples":[{"de":"Wo ist die Fernbedienung für den Fernseher?","en":"Where is the remote control for the TV?","ru":"Где пульт от телевизора?","vi":"Điều khiển từ xa cho TV ở đâu?","fa":"ریموت کنترل تلویزیون کجاست؟"},{"de":"Die Batterien der Fernbedienung sind leer.","en":"The batteries of the remote control are empty.","ru":"Батарейки в пульте разрядились.","vi":"Pin của điều khiển từ xa đã hết.","fa":"باتری های کنترل از راه دور خالی هستند."}]},{"word":"das Fernglas","en":"binoculars","ru":"бинокль","vi":"ống nhòm","fa":"the binoculars","examples":[{"de":"Mit dem Fernglas konnten wir die Krater des Mondes sehen.","en":"With the binoculars we could see the craters of the Moon.","ru":"В бинокль мы смогли увидеть кратеры Луны.","vi":"Với ống nhòm chúng ta có thể nhìn thấy các miệng hố trên mặt trăng.","fa":"با دوربین دوچشمی می‌توانستیم دهانه‌های ماه را ببینیم."},{"de":"Nimm das Fernglas mit, dann erkennst du die Sterne besser.","en":"Take the binoculars with you, then you will see the stars better.","ru":"Возьми с собой бинокль, тогда ты лучше разглядишь звёзды.","vi":"Mang theo ống nhòm để bạn có thể nhìn rõ các ngôi sao hơn.","fa":"دوربین دوچشمی همراه خود ببرید تا ستاره ها را بهتر ببینید."},{"de":"Durch das Fernglas wirkte der Planet ganz nah.","en":"Through the binoculars the planet seemed very close.","ru":"В бинокль планета казалась совсем близкой.","vi":"Qua ống nhòm, hành tinh này trông rất gần.","fa":"از طریق دوربین دوچشمی سیاره بسیار نزدیک به نظر می رسید."}]},{"word":"fernsehen","en":"to watch TV","ru":"смотреть телевизор","vi":"xem tivi","fa":"تلویزیون تماشا کن","examples":[{"de":"Abends sieht die ganze Familie zusammen fern.","en":"In the evening the whole family watches TV together.","ru":"По вечерам вся семья вместе смотрит телевизор.","vi":"Buổi tối cả nhà cùng nhau xem TV.","fa":"عصرها همه خانواده با هم تلویزیون تماشا می کنند."},{"de":"Ich sehe nicht gern lange fern, ich lese lieber.","en":"I don't like watching TV for long, I prefer to read.","ru":"Я не люблю долго смотреть телевизор, предпочитаю читать.","vi":"Tôi không thích xem TV trong thời gian dài, tôi thích đọc sách hơn.","fa":"من دوست ندارم برای مدت طولانی تلویزیون ببینم، مطالعه را ترجیح می دهم."}]},{"word":"der Fernseher","en":"television set","ru":"телевизор","vi":"tivi","fa":"the television","examples":[{"de":"Wir haben uns einen neuen Fernseher gekauft.","en":"We bought a new television set.","ru":"Мы купили себе новый телевизор.","vi":"Chúng tôi đã mua một chiếc tivi mới.","fa":"ما یک تلویزیون جدید خریدیم."},{"de":"Der Fernseher im Wohnzimmer ist kaputt.","en":"The television set in the living room is broken.","ru":"Телевизор в гостиной сломан.","vi":"Chiếc TV ở phòng khách bị hỏng.","fa":"تلویزیون اتاق نشیمن خراب است."},{"de":"Schalt bitte den Fernseher aus, bevor du schlafen gehst.","en":"Please switch off the television before you go to sleep.","ru":"Пожалуйста, выключи телевизор, прежде чем идти спать.","vi":"Hãy tắt TV trước khi bạn đi ngủ.","fa":"لطفا قبل از خواب تلویزیون را خاموش کنید."}]},{"word":"der Fernsehsender","en":"television channel/station","ru":"телеканал, телевизионная станция","vi":"đài truyền hình","fa":"the television station","examples":[{"de":"Welchen Fernsehsender schaust du am liebsten?","en":"Which television channel do you like watching most?","ru":"Какой телеканал ты смотришь охотнее всего?","vi":"Bạn thích xem kênh truyền hình nào nhất?","fa":"کدام کانال تلویزیونی را بیشتر دوست دارید؟"},{"de":"Der private Fernsehsender zeigt viel Werbung.","en":"The private television channel shows a lot of advertising.","ru":"Частный телеканал показывает много рекламы.","vi":"Đài truyền hình tư nhân chiếu rất nhiều quảng cáo.","fa":"تلویزیون خصوصی تبلیغات زیادی نشان می دهد."},{"de":"Ein neuer Fernsehsender hat gerade sein Programm gestartet.","en":"A new television station has just launched its programme.","ru":"Новый телеканал только что запустил своё вещание.","vi":"Một đài truyền hình mới vừa bắt đầu chương trình của mình.","fa":"یک شبکه تلویزیونی جدید به تازگی برنامه خود را آغاز کرده است."}]},{"word":"fertig","en":"ready, finished","ru":"готовый","vi":"đã hoàn thành","fa":"به پایان رسید","examples":[{"de":"Bist du fertig? Wir müssen jetzt los.","en":"Are you ready? We have to go now.","ru":"Ты готов? Нам пора идти.","vi":"Bạn đã sẵn sàng chưa? Chúng ta phải đi bây giờ.","fa":"آیا شما آماده اید؟ الان باید بریم"},{"de":"Ich bin mit meiner Hausaufgabe schon fertig.","en":"I'm already finished with my homework.","ru":"Я уже закончил домашнее задание.","vi":"Tôi đã làm xong bài tập về nhà rồi.","fa":"من قبلاً تکالیفم را تمام کرده ام."}]},{"word":"fest","en":"firm, fixed","ru":"твёрдый, крепкий; постоянный","vi":"đã sửa","fa":"ثابت","examples":[{"de":"Halt das Seil bitte ganz fest!","en":"Please hold the rope very firmly!","ru":"Держи верёвку крепко!","vi":"Hãy giữ chặt sợi dây!","fa":"لطفا طناب را محکم بگیرید!"},{"de":"Sie hat einen festen Job in einer großen Firma.","en":"She has a permanent job at a big company.","ru":"У неё постоянная работа в крупной компании.","vi":"Cô ấy có một công việc ổn định ở một công ty lớn.","fa":"او یک شغل دائمی در یک شرکت بزرگ دارد."}]},{"word":"das Fest","en":"celebration, festival","ru":"праздник","vi":"bữa tiệc","fa":"حزب","examples":[{"de":"Zur Hochzeit haben sie ein großes Fest organisiert.","en":"For the wedding they organized a big celebration.","ru":"На свадьбу они устроили большой праздник.","vi":"Họ tổ chức một bữa tiệc lớn cho đám cưới.","fa":"آنها یک جشن بزرگ برای عروسی ترتیب دادند."},{"de":"Das Dorf feiert jedes Jahr im Sommer ein Fest.","en":"The village celebrates a festival every summer.","ru":"В деревне каждое лето проводят праздник.","vi":"Làng tổ chức lễ hội vào mỗi mùa hè.","fa":"این روستا هر تابستان جشنواره ای را جشن می گیرد."}]},{"word":"festhalten","en":"to hold on to","ru":"держаться, крепко держать","vi":"chờ đã","fa":"نگه دارید","examples":[{"de":"Halt dich gut fest, der Bus fährt jetzt los!","en":"Hold on tight, the bus is about to leave!","ru":"Держись крепко, автобус сейчас тронется!","vi":"Hãy giữ chặt nhé, xe buýt sắp rời đi rồi!","fa":"محکم نگه دارید، اتوبوس در حال حرکت است!"},{"de":"Das Kind hielt die Hand seiner Mutter fest.","en":"The child held on to its mother's hand.","ru":"Ребёнок крепко держался за руку матери.","vi":"Cậu bé nắm chặt tay mẹ.","fa":"کودک دست مادرش را محکم گرفته بود."}]},{"word":"das Festival","en":"festival","ru":"фестиваль","vi":"lễ hội","fa":"جشنواره","examples":[{"de":"Auf dem Festival traten viele Tanzgruppen auf.","en":"Many dance groups performed at the festival.","ru":"На фестивале выступало много танцевальных коллективов.","vi":"Nhiều nhóm nhảy biểu diễn tại lễ hội.","fa":"بسیاری از گروه های رقص در این جشنواره به اجرای برنامه پرداختند."},{"de":"Das Festival findet jeden Sommer in der Stadt statt.","en":"The festival takes place in the city every summer.","ru":"Фестиваль проходит в городе каждое лето.","vi":"Lễ hội diễn ra vào mùa hè hàng năm ở thành phố.","fa":"این جشنواره هر تابستان در این شهر برگزار می شود."},{"de":"Wir tanzten die ganze Nacht auf dem Festival.","en":"We danced all night at the festival.","ru":"Мы протанцевали на фестивале всю ночь.","vi":"Chúng tôi nhảy múa suốt đêm tại lễ hội.","fa":"ما تمام شب را در جشنواره رقصیدیم."}]},{"word":"festlegen","en":"to determine, set","ru":"устанавливать, определять","vi":"đặt","fa":"مجموعه","examples":[{"de":"Wir müssen noch einen Termin für das Treffen festlegen.","en":"We still need to set a date for the meeting.","ru":"Нам ещё нужно назначить дату встречи.","vi":"Chúng ta vẫn cần phải ấn định ngày cho cuộc họp.","fa":"ما هنوز باید تاریخ ملاقات را تعیین کنیم."},{"de":"Die Regeln wurden schon vor Jahren festgelegt.","en":"The rules were established years ago.","ru":"Правила были установлены ещё несколько лет назад.","vi":"Các quy tắc đã được thiết lập từ nhiều năm trước.","fa":"قوانین سال ها پیش تعیین شده بود."}]},{"word":"festnehmen","en":"to arrest","ru":"задерживать, арестовывать","vi":"bắt giữ","fa":"دستگیری","examples":[{"de":"Die Polizei nahm den Verdächtigen fest.","en":"The police arrested the suspect.","ru":"Полиция задержала подозреваемого.","vi":"Cảnh sát đã bắt giữ nghi phạm.","fa":"پلیس مظنون را دستگیر کرد."},{"de":"Er wurde gestern Abend festgenommen.","en":"He was arrested last night.","ru":"Его арестовали прошлой ночью.","vi":"Anh ta đã bị bắt tối qua.","fa":"او دیشب دستگیر شد."},{"de":"Die Beamten nehmen den Täter am Bahnhof fest.","en":"The officers arrest the perpetrator at the station.","ru":"Сотрудники задерживают преступника на вокзале.","vi":"Cảnh sát bắt giữ hung thủ tại nhà ga xe lửa.","fa":"ماموران عامل جنایت را در ایستگاه قطار دستگیر کردند."}]},{"word":"festnehmen nimmt fest","en":"to arrest","ru":"арестовывать, задерживать","vi":"bắt giữ","fa":"دستگیر کردن","examples":[{"de":"Die Polizei hat den Dieb noch am selben Abend festgenommen.","en":"The police arrested the thief that same evening.","ru":"Полиция задержала вора в тот же вечер.","vi":"Cảnh sát đã bắt giữ tên trộm ngay tối hôm đó.","fa":"پلیس دزد را عصر همان روز دستگیر کرد."},{"de":"Er wurde wegen Betrugs festgenommen.","en":"He was arrested for fraud.","ru":"Его арестовали за мошенничество.","vi":"Anh ta bị bắt vì tội lừa đảo.","fa":"به جرم کلاهبرداری دستگیر شد."}]},{"word":"die Festplatte","en":"hard drive","ru":"жёсткий диск","vi":"ổ cứng","fa":"هارد دیسک","examples":[{"de":"Meine Festplatte ist fast voll, ich muss Daten löschen.","en":"My hard drive is almost full, I need to delete data.","ru":"Мой жёсткий диск почти заполнен, нужно удалить данные.","vi":"Ổ cứng của tôi gần đầy, tôi phải xóa dữ liệu.","fa":"هاردم تقریبا پر شده باید دیتا رو پاک کنم."},{"de":"Die alte Festplatte war kaputt, deshalb habe ich eine neue gekauft.","en":"The old hard drive was broken, so I bought a new one.","ru":"Старый жёсткий диск сломался, поэтому я купил новый.","vi":"Ổ cứng cũ bị hỏng nên tôi mua cái mới.","fa":"هارد قدیمی خراب شده بود، برای همین یک هارد جدید خریدم."}]},{"word":"festsetzen","en":"to set, fix","ru":"устанавливать, назначать","vi":"sửa chữa","fa":"رفع کنید","examples":[{"de":"Der Preis für die Tickets wurde vom Veranstalter festgesetzt.","en":"The price for the tickets was set by the organizer.","ru":"Цена на билеты была установлена организатором.","vi":"Giá vé do ban tổ chức ấn định.","fa":"قیمت بلیط ها توسط برگزار کننده تعیین شده است."},{"de":"Man hat den Termin für die Prüfung schon festgesetzt.","en":"The date for the exam has already been set.","ru":"Дата экзамена уже назначена.","vi":"Ngày thi đã được ấn định.","fa":"تاریخ برگزاری آزمون قبلاً تعیین شده است."}]},{"word":"feststehen","en":"to be certain","ru":"быть точно установленным","vi":"đứng vững","fa":"محکم بایست","examples":[{"de":"Es steht noch nicht fest, wer den Preis gewinnt.","en":"It is not yet certain who will win the prize.","ru":"Пока не известно точно, кто выиграет приз.","vi":"Hiện vẫn chưa rõ ai sẽ giành được giải thưởng.","fa":"هنوز مشخص نیست چه کسی برنده جایزه خواهد شد."},{"de":"Der Termin für die Hochzeit steht schon fest.","en":"The date for the wedding is already fixed.","ru":"Дата свадьбы уже точно определена.","vi":"Ngày tổ chức đám cưới đã được định sẵn.","fa":"تاریخ عروسی از قبل تعیین شده است."}]},{"word":"feststellen","en":"to notice, find out","ru":"устанавливать, замечать, обнаруживать","vi":"xác định","fa":"تعیین کنید","examples":[{"de":"Der Arzt konnte keine Krankheit feststellen.","en":"The doctor could not find any illness.","ru":"Врач не смог обнаружить никакой болезни.","vi":"Bác sĩ không thể tìm ra bệnh gì.","fa":"دکتر هیچ بیماری پیدا نکرد."},{"de":"Ich habe erst zu Hause festgestellt, dass mein Schlüssel fehlt.","en":"I only noticed at home that my key was missing.","ru":"Только дома я заметил, что у меня пропал ключ.","vi":"Tôi chỉ phát hiện ra khi về đến nhà rằng chìa khóa của tôi đã bị mất.","fa":"فقط وقتی به خانه رسیدم متوجه شدم که کلیدم گم شده است."}]},{"word":"fett","en":"fatty, greasy","ru":"жирный","vi":"béo","fa":"چربی","examples":[{"de":"Das Essen im Restaurant war mir zu fett.","en":"The food at the restaurant was too greasy for me.","ru":"Еда в ресторане показалась мне слишком жирной.","vi":"Thức ăn trong nhà hàng quá béo đối với tôi.","fa":"غذای رستوران برای من خیلی چرب بود."},{"de":"Fettes Fleisch esse ich nicht so gern.","en":"I don't really like eating fatty meat.","ru":"Я не очень люблю жирное мясо.","vi":"Tôi thực sự không thích ăn thịt mỡ.","fa":"من زیاد دوست ندارم گوشت چرب بخورم."}]},{"word":"fettig","en":"greasy","ru":"жирный (о еде)","vi":"nhờn","fa":"چرب","examples":[{"de":"Das frittierte Essen war mir zu fettig.","en":"The fried food was too greasy for me.","ru":"Жареная еда была для меня слишком жирной.","vi":"Đồ chiên quá béo đối với tôi.","fa":"غذای سرخ شده برای من خیلی چرب بود."},{"de":"Fettige Speisen liegen schwer im Magen.","en":"Greasy foods sit heavily in the stomach.","ru":"Жирная пища тяжело лежит в желудке.","vi":"Thức ăn nhiều dầu mỡ gây khó chịu cho dạ dày.","fa":"غذاهای چرب برای معده سخت هستند."},{"de":"Die Pommes waren leider sehr fettig.","en":"The chips were unfortunately very greasy.","ru":"Картошка фри, к сожалению, была очень жирной.","vi":"Thật không may là khoai tây chiên rất béo.","fa":"متاسفانه سیب زمینی سرخ شده خیلی چرب بود."}]},{"word":"feucht","en":"damp, humid","ru":"влажный","vi":"ẩm ướt","fa":"مرطوب","examples":[{"de":"Nach dem Regen war die Luft noch feucht.","en":"After the rain the air was still humid.","ru":"После дождя воздух был ещё влажным.","vi":"Không khí vẫn ẩm ướt sau cơn mưa.","fa":"بعد از بارندگی هوا هنوز مرطوب بود."},{"de":"Wisch den Tisch mit einem feuchten Tuch ab.","en":"Wipe the table with a damp cloth.","ru":"Протри стол влажной тряпкой.","vi":"Lau bàn bằng vải ẩm.","fa":"میز را با یک پارچه مرطوب پاک کنید."}]},{"word":"die Feuchtigkeit","en":"humidity, moisture","ru":"влажность, сырость","vi":"độ ẩm","fa":"رطوبت","examples":[{"de":"Die hohe Feuchtigkeit macht die Hitze noch unangenehmer.","en":"The high humidity makes the heat even more unpleasant.","ru":"Высокая влажность делает жару ещё неприятнее.","vi":"Độ ẩm cao khiến cái nóng càng khó chịu hơn.","fa":"رطوبت بالا باعث می شود گرما بیشتر ناراحت کننده باشد."},{"de":"An der Küste ist die Feuchtigkeit oft sehr hoch.","en":"On the coast the humidity is often very high.","ru":"На побережье влажность часто очень высокая.","vi":"Độ ẩm thường rất cao trên bờ biển.","fa":"رطوبت اغلب در ساحل بسیار زیاد است."},{"de":"Durch die Feuchtigkeit beschlugen die Fensterscheiben.","en":"The window panes fogged up because of the moisture.","ru":"Из-за сырости оконные стёкла запотели.","vi":"Độ ẩm khiến kính cửa sổ bị đọng sương.","fa":"رطوبت باعث مه آلود شدن شیشه های پنجره شد."}]},{"word":"das Feuer","en":"fire","ru":"огонь","vi":"ngọn lửa","fa":"آتش","examples":[{"de":"Wir haben am Strand ein Feuer gemacht.","en":"We made a fire on the beach.","ru":"Мы развели огонь на пляже.","vi":"Chúng tôi đốt lửa trên bãi biển.","fa":"در ساحل آتش زدیم."},{"de":"Bei dem Feuer wurde niemand verletzt.","en":"No one was injured in the fire.","ru":"Во время пожара никто не пострадал.","vi":"Không có ai bị thương trong vụ cháy.","fa":"در این آتش سوزی به کسی آسیب نرسید."}]},{"word":"die Feuerwehr","en":"fire brigade","ru":"пожарная охрана, пожарная команда","vi":"sở cứu hỏa","fa":"آتش نشانی","examples":[{"de":"Ruf sofort die Feuerwehr an!","en":"Call the fire brigade immediately!","ru":"Немедленно позвони пожарным!","vi":"Hãy gọi cho sở cứu hỏa ngay lập tức!","fa":"بلافاصله با آتش نشانی تماس بگیرید!"},{"de":"Die Feuerwehr war innerhalb von zehn Minuten da.","en":"The fire brigade was there within ten minutes.","ru":"Пожарные прибыли в течение десяти минут.","vi":"Sở cứu hỏa đã có mặt ở đó trong vòng mười phút.","fa":"آتش نشانی ظرف ده دقیقه آنجا بود."},{"de":"Mein Bruder arbeitet bei der freiwilligen Feuerwehr.","en":"My brother works for the volunteer fire brigade.","ru":"Мой брат работает в добровольной пожарной команде.","vi":"Anh trai tôi làm việc cho sở cứu hỏa tình nguyện.","fa":"برادرم برای آتش نشانی داوطلب کار می کند."}]},{"word":"das Feuerzeug","en":"lighter","ru":"зажигалка","vi":"cái nhẹ hơn","fa":"the lighter","examples":[{"de":"Hast du ein Feuerzeug dabei?","en":"Do you have a lighter with you?","ru":"У тебя есть с собой зажигалка?","vi":"Bạn có mang theo bật lửa không?","fa":"فندک همراهت داری؟"},{"de":"Mein Feuerzeug funktioniert nicht mehr.","en":"My lighter doesn't work any more.","ru":"Моя зажигалка больше не работает.","vi":"Bật lửa của tôi không còn hoạt động nữa.","fa":"فندک من دیگر کار نمی کند."},{"de":"Er zündete die Kerze mit einem Feuerzeug an.","en":"He lit the candle with a lighter.","ru":"Он зажёг свечу зажигалкой.","vi":"Anh thắp nến bằng bật lửa.","fa":"شمع را با فندک روشن کرد."}]},{"word":"das Fieber","en":"fever","ru":"температура, жар","vi":"cơn sốt","fa":"تب","examples":[{"de":"Mein Sohn hat hohes Fieber und muss im Bett bleiben.","en":"My son has a high fever and has to stay in bed.","ru":"У моего сына высокая температура, ему нужно лежать в постели.","vi":"Con trai tôi bị sốt cao và phải nằm trên giường.","fa":"پسرم تب شدید دارد و باید در رختخواب بماند."},{"de":"Bei Fieber sollte man viel trinken.","en":"When you have a fever you should drink a lot.","ru":"При температуре нужно много пить.","vi":"Nếu bị sốt thì nên uống nhiều.","fa":"اگر تب دارید باید زیاد بنوشید."}]},{"word":"die Figur","en":"figure","ru":"фигура","vi":"hình","fa":"شکل","examples":[{"de":"Sie achtet sehr auf ihre Figur und macht viel Sport.","en":"She pays close attention to her figure and does a lot of sports.","ru":"Она очень следит за своей фигурой и много занимается спортом.","vi":"Cô ấy rất chú ý đến hình thể của mình và chơi rất nhiều môn thể thao.","fa":"او به اندام خود اهمیت زیادی می دهد و ورزش های زیادی انجام می دهد."},{"de":"Im Museum stehen alte Figuren aus Holz.","en":"In the museum there are old wooden figures.","ru":"В музее стоят старые деревянные фигуры.","vi":"Có những bức tượng gỗ cũ trong bảo tàng.","fa":"مجسمه های چوبی قدیمی در موزه وجود دارد."}]},{"word":"der Film","en":"film, movie","ru":"фильм","vi":"bộ phim","fa":"فیلم","examples":[{"de":"Welchen Film wollen wir heute Abend sehen?","en":"Which film do we want to watch tonight?","ru":"Какой фильм мы посмотрим сегодня вечером?","vi":"Tối nay chúng ta muốn xem phim gì?","fa":"کدام فیلم را امشب می خواهیم ببینیم؟"},{"de":"Der neue Film hat mir sehr gut gefallen.","en":"I liked the new film very much.","ru":"Мне очень понравился новый фильм.","vi":"Tôi thực sự thích bộ phim mới.","fa":"من فیلم جدید را خیلی دوست داشتم."}]},{"word":"finanziell","en":"financial","ru":"финансовый","vi":"tài chính","fa":"مالی","examples":[{"de":"Sie haben finanzielle Probleme.","en":"They have financial problems.","ru":"У них финансовые проблемы.","vi":"Bạn gặp vấn đề về tài chính.","fa":"مشکلات مالی دارید."},{"de":"Meine Eltern unterstützen mich finanziell.","en":"My parents support me financially.","ru":"Мои родители поддерживают меня финансово.","vi":"Bố mẹ tôi hỗ trợ tôi về mặt tài chính.","fa":"پدر و مادرم از من حمایت مالی می کنند."},{"de":"Die finanzielle Lage der Firma ist schwierig.","en":"The company's financial situation is difficult.","ru":"Финансовое положение фирмы сложное.","vi":"Tình hình tài chính của công ty đang khó khăn.","fa":"وضعیت مالی شرکت سخت است."}]},{"word":"finanzieren","en":"to finance","ru":"финансировать","vi":"tài chính","fa":"امور مالی","examples":[{"de":"Wie wollt ihr den Hausbau finanzieren?","en":"How do you plan to finance building the house?","ru":"Как вы собираетесь финансировать строительство дома?","vi":"Bạn muốn tài trợ xây dựng một ngôi nhà như thế nào?","fa":"چگونه می خواهید بودجه ساخت خانه را تامین کنید؟"},{"de":"Das Projekt wird von der Stadt finanziert.","en":"The project is financed by the city.","ru":"Проект финансируется городом.","vi":"Dự án được thành phố tài trợ.","fa":"این پروژه توسط شهرداری تامین می شود."}]},{"word":"Das finde ich auch","en":"I think so too (agreement)","ru":"Я тоже так думаю (согласие)","vi":"tôi cũng nghĩ vậy","fa":"من هم همینطور فکر می کنم","examples":[{"de":"Das finde ich auch, der Plan ist gut.","en":"I think so too, the plan is good.","ru":"Я тоже так думаю, план хороший.","vi":"Tôi cũng nghĩ vậy, kế hoạch này hay đấy.","fa":"من هم همینطور فکر می کنم، طرح خوبی است."}]},{"word":"finden","en":"to find","ru":"находить; считать","vi":"tìm thấy","fa":"پیدا کردن","examples":[{"de":"Ich kann meinen Schlüssel nicht finden.","en":"I can't find my key.","ru":"Я не могу найти свой ключ.","vi":"Tôi không thể tìm thấy chìa khóa của mình.","fa":"من نمی توانم کلید خود را پیدا کنم."},{"de":"Wie findest du meine neue Frisur?","en":"What do you think of my new haircut?","ru":"Как тебе моя новая причёска?","vi":"Bạn nghĩ gì về kiểu tóc mới của tôi?","fa":"نظر شما در مورد مدل موی جدید من چیست؟"}]},{"word":"der Finger","en":"finger","ru":"палец","vi":"ngón tay","fa":"انگشت","examples":[{"de":"Ich habe mir beim Kochen in den Finger geschnitten.","en":"I cut my finger while cooking.","ru":"Я порезал палец во время готовки.","vi":"Tôi bị đứt tay khi đang nấu ăn.","fa":"هنگام آشپزی انگشتم را بریدم."},{"de":"Sie zeigte mit dem Finger auf die Karte.","en":"She pointed at the map with her finger.","ru":"Она указала пальцем на карту.","vi":"Cô chỉ tay vào bản đồ.","fa":"انگشتش را به سمت نقشه گرفت."}]},{"word":"die Finsternis","en":"eclipse, darkness","ru":"затмение; мрак, тьма","vi":"bóng tối","fa":"تاریکی","examples":[{"de":"Während der Finsternis wurde es plötzlich dunkel.","en":"During the eclipse it suddenly grew dark.","ru":"Во время затмения внезапно стало темно.","vi":"Trong lúc nhật thực, trời đột nhiên trở nên tối tăm.","fa":"در طول ماه گرفتگی ناگهان تاریک شد."},{"de":"Eine Finsternis des Mondes kann man mit bloßem Auge sehen.","en":"A lunar eclipse can be seen with the naked eye.","ru":"Лунное затмение можно увидеть невооружённым глазом.","vi":"Nhật thực có thể được nhìn thấy bằng mắt thường.","fa":"ماه گرفتگی را می توان با چشم غیر مسلح دید."},{"de":"Die nächste Finsternis findet im Herbst statt.","en":"The next eclipse takes place in autumn.","ru":"Следующее затмение состоится осенью.","vi":"Nhật thực tiếp theo sẽ diễn ra vào mùa thu.","fa":"کسوف بعدی در پاییز اتفاق می افتد."}]},{"word":"die Firma","en":"company","ru":"фирма, компания","vi":"công ty","fa":"شرکت","examples":[{"de":"Er arbeitet seit zehn Jahren bei derselben Firma.","en":"He has been working at the same company for ten years.","ru":"Он работает в одной и той же компании уже десять лет.","vi":"Anh ấy đã làm việc ở cùng một công ty được mười năm.","fa":"او ده سال است که در همان شرکت کار می کند."},{"de":"Die Firma sucht neue Mitarbeiter.","en":"The company is looking for new employees.","ru":"Компания ищет новых сотрудников.","vi":"Công ty đang tìm kiếm nhân viên mới.","fa":"این شرکت به دنبال کارمندان جدید است."}]},{"word":"flach","en":"flat","ru":"плоский, ровный","vi":"bằng phẳng","fa":"تخت","examples":[{"de":"Das Land hier ist sehr flach, es gibt kaum Berge.","en":"The land here is very flat, there are hardly any mountains.","ru":"Местность здесь очень плоская, гор почти нет.","vi":"Đất ở đây rất bằng phẳng, hầu như không có ngọn núi nào.","fa":"زمین اینجا بسیار هموار است، کوه به سختی وجود دارد."},{"de":"Sie trägt lieber flache Schuhe als hohe Absätze.","en":"She prefers flat shoes to high heels.","ru":"Она предпочитает плоскую обувь высоким каблукам.","vi":"Cô thích đi giày bệt hơn giày cao gót.","fa":"او پوشیدن کفش های تخت را به کفش های پاشنه بلند ترجیح می دهد."}]},{"word":"die Fläche","en":"area, surface","ru":"площадь, поверхность","vi":"khu vực","fa":"منطقه","examples":[{"de":"Der Park hat eine Fläche von zehn Hektar.","en":"The park has an area of ten hectares.","ru":"Площадь парка составляет десять гектаров.","vi":"Công viên có diện tích mười ha.","fa":"این پارک ده هکتار مساحت دارد."},{"de":"Die Fläche des Tisches ist ganz glatt.","en":"The surface of the table is completely smooth.","ru":"Поверхность стола совершенно гладкая.","vi":"Bề mặt của bàn hoàn toàn mịn màng.","fa":"سطح میز کاملا صاف است."}]},{"word":"die Flasche","en":"bottle","ru":"бутылка","vi":"cái chai","fa":"بطری","examples":[{"de":"Kannst du mir bitte eine Flasche Wasser bringen?","en":"Can you bring me a bottle of water, please?","ru":"Принеси мне, пожалуйста, бутылку воды.","vi":"Bạn có thể vui lòng mang cho tôi một chai nước được không?","fa":"میشه لطفا یه بطری آب برام بیارید؟"},{"de":"Die leeren Flaschen bringen wir zum Recycling.","en":"We take the empty bottles to be recycled.","ru":"Мы отвозим пустые бутылки на переработку.","vi":"Chúng tôi lấy những chai rỗng để tái chế.","fa":"بطری های خالی را برای بازیافت می بریم."}]},{"word":"der Fleck","en":"stain","ru":"пятно","vi":"vết bẩn","fa":"لکه","examples":[{"de":"Auf meinem Hemd ist ein Fleck von der Soße.","en":"There's a stain from the sauce on my shirt.","ru":"На моей рубашке пятно от соуса.","vi":"Có vết nước sốt trên áo tôi.","fa":"روی پیراهنم لکه سس هست"},{"de":"Der Fleck geht mit warmem Wasser leicht raus.","en":"The stain comes out easily with warm water.","ru":"Пятно легко отстирывается тёплой водой.","vi":"Vết bẩn dễ dàng bong ra bằng nước ấm.","fa":"لکه به راحتی با آب گرم خارج می شود."}]},{"word":"das Fleisch","en":"meat","ru":"мясо","vi":"thịt","fa":"گوشت","examples":[{"de":"Wir kaufen unser Fleisch immer beim Metzger nebenan.","en":"We always buy our meat from the butcher next door.","ru":"Мы всегда покупаем мясо у соседнего мясника.","vi":"Chúng tôi luôn mua thịt từ người bán thịt bên cạnh.","fa":"ما همیشه گوشتمان را از قصاب همسایه می خریم."},{"de":"Sie isst kein Fleisch mehr, seit sie Vegetarierin ist.","en":"She hasn't eaten meat anymore since she became a vegetarian.","ru":"Она больше не ест мясо с тех пор, как стала вегетарианкой.","vi":"Cô ấy không còn ăn thịt kể từ khi cô ấy ăn chay.","fa":"او از زمانی که گیاهخوار شد دیگر گوشت نمی خورد."}]},{"word":"der Fleischhauer","en":"butcher","ru":"мясник","vi":"người bán thịt","fa":"قصاب","examples":[{"de":"Der Fleischhauer um die Ecke hat immer frisches Fleisch.","en":"The butcher around the corner always has fresh meat.","ru":"У мясника за углом всегда свежее мясо.","vi":"Người bán thịt quanh góc luôn có thịt tươi.","fa":"قصاب این گوشه همیشه گوشت تازه دارد."},{"de":"Ich kaufe das Fleisch für den Sonntagsbraten beim Fleischhauer.","en":"I buy the meat for the Sunday roast from the butcher.","ru":"Я покупаю мясо для воскресного жаркого у мясника.","vi":"Tôi mua thịt nướng vào Chủ nhật từ người bán thịt.","fa":"من گوشت کباب یکشنبه را از قصاب می خرم."}]},{"word":"fleißig","en":"hardworking, diligent","ru":"прилежный, трудолюбивый","vi":"chăm chỉ","fa":"سخت کوش","examples":[{"de":"Sie ist eine sehr fleißige Studentin und lernt jeden Tag.","en":"She is a very diligent student and studies every day.","ru":"Она очень прилежная студентка и учится каждый день.","vi":"Cô ấy là một học sinh rất chăm chỉ và học tập mỗi ngày.","fa":"او دانش آموز بسیار سخت کوشی است و هر روز درس می خواند."},{"de":"Wenn du fleißig übst, wirst du die Prüfung schaffen.","en":"If you practice diligently, you will pass the exam.","ru":"Если будешь усердно заниматься, ты сдашь экзамен.","vi":"Nếu bạn luyện tập chăm chỉ, bạn sẽ vượt qua kỳ thi.","fa":"اگر سخت تمرین کنید در امتحان موفق خواهید شد."}]},{"word":"flexibel","en":"flexible","ru":"гибкий","vi":"linh hoạt","fa":"قابل انعطاف","examples":[{"de":"Meine Arbeitszeiten sind zum Glück sehr flexibel.","en":"Luckily my working hours are very flexible.","ru":"К счастью, мой рабочий график очень гибкий.","vi":"May mắn thay, giờ làm việc của tôi rất linh hoạt.","fa":"خوشبختانه ساعات کاری من بسیار انعطاف پذیر است."},{"de":"Man muss im Leben flexibel bleiben und sich anpassen können.","en":"You have to stay flexible in life and be able to adapt.","ru":"В жизни нужно оставаться гибким и уметь приспосабливаться.","vi":"Bạn phải linh hoạt trong cuộc sống và có khả năng thích nghi.","fa":"شما باید در زندگی انعطاف پذیر باقی بمانید و بتوانید خود را وفق دهید."}]},{"word":"fliegen","en":"to fly","ru":"летать","vi":"bay","fa":"پرواز کن","examples":[{"de":"Wir fliegen nächste Woche nach Spanien.","en":"We are flying to Spain next week.","ru":"На следующей неделе мы летим в Испанию.","vi":"Chúng tôi sẽ bay đến Tây Ban Nha vào tuần tới.","fa":"هفته آینده به اسپانیا پرواز می کنیم."},{"de":"Der Vogel flog schnell aus dem Fenster.","en":"The bird quickly flew out of the window.","ru":"Птица быстро вылетела из окна.","vi":"Con chim nhanh chóng bay ra ngoài cửa sổ.","fa":"پرنده به سرعت از پنجره بیرون پرید."}]},{"word":"fliehen","en":"to flee","ru":"бежать, спасаться бегством","vi":"chạy trốn","fa":"فرار کن","examples":[{"de":"Viele Menschen mussten aus ihrer Heimat fliehen.","en":"Many people had to flee their homeland.","ru":"Многим людям пришлось бежать из своей родины.","vi":"Nhiều người đã phải rời bỏ nhà cửa.","fa":"بسیاری از مردم مجبور به ترک خانه های خود شدند."},{"de":"Der Dieb floh, bevor die Polizei ankam.","en":"The thief fled before the police arrived.","ru":"Вор скрылся до приезда полиции.","vi":"Tên trộm đã bỏ trốn trước khi cảnh sát đến.","fa":"دزد قبل از رسیدن پلیس متواری شد."}]},{"word":"die Fliehkraft","en":"centrifugal force","ru":"центробежная сила","vi":"lực ly tâm","fa":"نیروی گریز از مرکز","examples":[{"de":"In der Kurve spürt man die Fliehkraft im Auto.","en":"In the bend you feel the centrifugal force in the car.","ru":"На повороте в машине чувствуешь центробежную силу.","vi":"Bạn có thể cảm nhận được lực ly tâm trong xe khi vào cua.","fa":"هنگام پیچیدن می توانید نیروی گریز از مرکز را در خودرو احساس کنید."},{"de":"Die Fliehkraft drückt das Wasser nach außen.","en":"The centrifugal force pushes the water outwards.","ru":"Центробежная сила выталкивает воду наружу.","vi":"Lực ly tâm đẩy nước ra ngoài.","fa":"نیروی گریز از مرکز آب را به سمت بیرون هل می دهد."},{"de":"Beim Karussell wirkt eine starke Fliehkraft.","en":"On the merry-go-round a strong centrifugal force acts.","ru":"На карусели действует сильная центробежная сила.","vi":"Một lực ly tâm mạnh tác dụng lên băng chuyền.","fa":"یک نیروی گریز از مرکز قوی روی چرخ فلک وارد می شود."}]},{"word":"fließen","en":"to flow","ru":"течь","vi":"dòng chảy","fa":"جریان","examples":[{"de":"Der Fluss fließt durch die ganze Stadt.","en":"The river flows through the whole city.","ru":"Река протекает через весь город.","vi":"Dòng sông chảy qua toàn bộ thành phố.","fa":"رودخانه از کل شهر می گذرد."},{"de":"Das Wasser fließt langsam den Berg hinunter.","en":"The water flows slowly down the mountain.","ru":"Вода медленно стекает с горы.","vi":"Nước từ từ chảy xuống núi.","fa":"آب به آرامی از کوه سرازیر می شود."}]},{"word":"fließend","en":"fluent, flowing","ru":"беглый, свободный (о речи); текущий","vi":"trôi chảy","fa":"روان","examples":[{"de":"Sie spricht fließend Deutsch.","en":"She speaks fluent German.","ru":"Она свободно говорит по-немецки.","vi":"Cô ấy nói tiếng Đức trôi chảy.","fa":"او آلمانی را روان صحبت می کند."},{"de":"In der Wohnung gibt es fließendes Wasser.","en":"There is running water in the flat.","ru":"В квартире есть проточная вода.","vi":"Có nước máy trong căn hộ.","fa":"آب لوله کشی در آپارتمان وجود دارد."},{"de":"Er beherrscht drei Sprachen fließend.","en":"He has a fluent command of three languages.","ru":"Он свободно владеет тремя языками.","vi":"Anh ấy thông thạo ba thứ tiếng.","fa":"او به سه زبان مسلط است."}]},{"word":"die Flinte ins Korn werfen","en":"to give up / throw in the towel","ru":"опустить руки, сдаться","vi":"bỏ cuộc/ném khăn đi","fa":"تسلیم شدن / دست کشیدن","examples":[{"de":"Auch wenn es schwer ist, wirf nicht gleich die Flinte ins Korn.","en":"Even if it's hard, don't just give up right away.","ru":"Даже если трудно, не опускай сразу руки.","vi":"Ngay cả khi điều đó khó khăn, đừng bỏ cuộc ngay lập tức.","fa":"حتی اگر سخت است، بلافاصله حوله را نیندازید."}]},{"word":"die Flitterwochen","en":"a honeymoon (the holiday after a wedding; used in the plural)","ru":"медовый месяц (отпуск после свадьбы; используется во мн. числе)","vi":"tuần trăng mật","fa":"ماه عسل","examples":[{"de":"Gibt es Flitterwochen in deinem Heimatland?","en":"Are there honeymoons in your home country?","ru":"У вас на родине есть медовый месяц?","vi":"Có tuần trăng mật ở quê hương bạn không?","fa":"آیا در کشور شما ماه عسل وجود دارد؟"},{"de":"Für die Flitterwochen fliegen sie nach Griechenland.","en":"For their honeymoon they are flying to Greece.","ru":"В медовый месяц они летят в Грецию.","vi":"Họ bay đến Hy Lạp để hưởng tuần trăng mật.","fa":"آنها برای ماه عسل خود به یونان می روند."},{"de":"Wir verbringen unsere Flitterwochen auf einer kleinen Insel.","en":"We are spending our honeymoon on a small island.","ru":"Мы проводим медовый месяц на маленьком острове.","vi":"Chúng tôi đang hưởng tuần trăng mật trên một hòn đảo nhỏ.","fa":"ماه عسل خود را در یک جزیره کوچک می گذرانیم."}]},{"word":"der Flohmarkt","en":"flea market","ru":"блошиный рынок","vi":"chợ trời","fa":"بازار دستفروشی","examples":[{"de":"Am Samstag gehen wir auf den Flohmarkt.","en":"On Saturday we're going to the flea market.","ru":"В субботу мы идём на блошиный рынок.","vi":"Thứ bảy chúng tôi đi chợ trời.","fa":"شنبه میریم بازار کثافت."},{"de":"Auf dem Flohmarkt habe ich ein altes Buch billig gekauft.","en":"At the flea market I bought an old book cheaply.","ru":"На блошином рынке я дёшево купил старую книгу.","vi":"Tôi mua được một cuốn sách cũ với giá rẻ ở chợ trời.","fa":"من یک کتاب قدیمی را ارزان از بازار فروش خریدم."}]},{"word":"die Flöte","en":"flute","ru":"флейта","vi":"cây sáo","fa":"فلوت","examples":[{"de":"Meine Tochter lernt seit einem Jahr Flöte spielen.","en":"My daughter has been learning to play the flute for a year.","ru":"Моя дочь уже год учится играть на флейте.","vi":"Con gái tôi đã học thổi sáo được một năm.","fa":"دخترم یک سال است که نواختن فلوت را یاد می گیرد."},{"de":"Er spielte ein ruhiges Lied auf der Flöte.","en":"He played a calm song on the flute.","ru":"Он сыграл спокойную мелодию на флейте.","vi":"Anh ấy thổi một bài hát lặng lẽ trên cây sáo.","fa":"او یک آهنگ آرام را روی فلوت نواخت."}]},{"word":"die Flucht","en":"escape, flight","ru":"побег, бегство","vi":"sự trốn thoát","fa":"the escape","examples":[{"de":"Die Flucht über die Grenze war sehr gefährlich.","en":"The escape across the border was very dangerous.","ru":"Побег через границу был очень опасным.","vi":"Việc trốn qua biên giới rất nguy hiểm.","fa":"فرار از آن سوی مرز بسیار خطرناک بود."},{"de":"Dem Gefangenen gelang die Flucht aus dem Gefängnis.","en":"The prisoner managed to escape from prison.","ru":"Заключённому удался побег из тюрьмы.","vi":"Người tù đã trốn thoát được khỏi nhà tù.","fa":"این زندانی موفق به فرار از زندان شد."},{"de":"Viele Menschen sind auf der Flucht vor dem Krieg.","en":"Many people are fleeing from the war.","ru":"Многие люди спасаются бегством от войны.","vi":"Nhiều người đang chạy trốn chiến tranh.","fa":"بسیاری از مردم از جنگ فرار می کنند."}]},{"word":"der Flug","en":"flight","ru":"полёт, рейс","vi":"chuyến bay","fa":"پرواز","examples":[{"de":"Unser Flug nach Berlin hat sich um zwei Stunden verspätet.","en":"Our flight to Berlin was delayed by two hours.","ru":"Наш рейс в Берлин задержался на два часа.","vi":"Chuyến bay của chúng tôi đến Berlin bị hoãn hai giờ.","fa":"پرواز ما به برلین با دو ساعت تاخیر انجام شد."},{"de":"Der Flug dauert ungefähr drei Stunden.","en":"The flight takes about three hours.","ru":"Полёт длится примерно три часа.","vi":"Chuyến bay kéo dài khoảng ba giờ.","fa":"The flight lasts approximately three hours."}]},{"word":"der Flugbegleiter","en":"flight attendant, steward","ru":"бортпроводник, стюард","vi":"tiếp viên hàng không","fa":"مهماندار هواپیما","examples":[{"de":"Der Flugbegleiter brachte uns Getränke.","en":"The flight attendant brought us drinks.","ru":"Бортпроводник принёс нам напитки.","vi":"Tiếp viên hàng không mang đồ uống cho chúng tôi.","fa":"مهماندار برای ما نوشیدنی آورد."},{"de":"Mein Cousin arbeitet als Flugbegleiter bei einer großen Fluglinie.","en":"My cousin works as a flight attendant for a large airline.","ru":"Мой двоюродный брат работает бортпроводником в крупной авиакомпании.","vi":"Anh họ tôi làm tiếp viên hàng không cho một hãng hàng không lớn.","fa":"پسر عموی من به عنوان مهماندار هواپیما در یک شرکت هواپیمایی بزرگ کار می کند."},{"de":"Der Flugbegleiter erklärte die Sicherheitsvorschriften.","en":"The flight attendant explained the safety instructions.","ru":"Бортпроводник объяснил правила безопасности.","vi":"Tiếp viên hàng không giải thích các quy định an toàn.","fa":"مهماندار هواپیما مقررات ایمنی را توضیح داد."}]},{"word":"der Flur","en":"hallway","ru":"коридор, прихожая","vi":"hành lang","fa":"راهرو","examples":[{"de":"Häng deine Jacke bitte im Flur auf.","en":"Please hang your jacket in the hallway.","ru":"Повесь, пожалуйста, куртку в прихожей.","vi":"Vui lòng treo áo khoác của bạn ở hành lang.","fa":"لطفا ژاکت خود را در راهرو آویزان کنید."},{"de":"Im Flur der Schule hängen Bilder der Schüler.","en":"Pictures by the students hang in the school hallway.","ru":"В школьном коридоре висят рисунки учеников.","vi":"Hình ảnh học sinh được treo ở hành lang trường học.","fa":"عکس های دانش آموزان در راهرو مدرسه آویزان شده است."}]},{"word":"der Fluss","en":"river","ru":"река","vi":"con sông","fa":"رودخانه","examples":[{"de":"Der Rhein ist einer der längsten Flüsse Europas.","en":"The Rhine is one of the longest rivers in Europe.","ru":"Рейн — одна из самых длинных рек Европы.","vi":"Sông Rhine là một trong những con sông dài nhất ở châu Âu.","fa":"رود راین یکی از طولانی ترین رودهای اروپاست."},{"de":"Wir sind im Sommer oft im Fluss geschwommen.","en":"In summer we often swam in the river.","ru":"Летом мы часто купались в реке.","vi":"Chúng tôi thường bơi ở sông vào mùa hè.","fa":"ما اغلب در تابستان در رودخانه شنا می کردیم."}]},{"word":"flüssig","en":"liquid (in liquid state)","ru":"жидкий","vi":"chất lỏng","fa":"مایع","examples":[{"de":"Bei Zimmertemperatur ist Wasser flüssig.","en":"At room temperature water is liquid.","ru":"При комнатной температуре вода жидкая.","vi":"Ở nhiệt độ phòng, nước ở dạng lỏng.","fa":"در دمای اتاق، آب مایع است."},{"de":"Wenn man Eis erwärmt, wird es flüssig.","en":"When you heat ice, it becomes liquid.","ru":"Если нагреть лёд, он становится жидким.","vi":"Khi bạn làm nóng đá, nó sẽ trở thành chất lỏng.","fa":"وقتی یخ را گرم می کنید به مایع تبدیل می شود."},{"de":"Flüssiges Metall ist sehr heiß und gefährlich.","en":"Liquid metal is very hot and dangerous.","ru":"Жидкий металл очень горячий и опасный.","vi":"Kim loại lỏng rất nóng và nguy hiểm.","fa":"فلز مایع بسیار داغ و خطرناک است."}]},{"word":"die Flüssigkeit","en":"liquid","ru":"жидкость","vi":"chất lỏng","fa":"مایع","examples":[{"de":"Man darf im Flugzeug keine großen Mengen Flüssigkeit mitnehmen.","en":"You are not allowed to bring large amounts of liquid on the plane.","ru":"В самолёт нельзя брать большое количество жидкости.","vi":"Bạn không được phép mang theo một lượng lớn chất lỏng lên máy bay.","fa":"شما مجاز نیستید مقدار زیادی مایعات را با خود در هواپیما ببرید."},{"de":"Aus der Wunde trat eine klare Flüssigkeit aus.","en":"A clear liquid came out of the wound.","ru":"Из раны сочилась прозрачная жидкость.","vi":"Một chất lỏng trong suốt chảy ra từ vết thương.","fa":"مایع شفافی از زخم خارج شد."}]},{"word":"die Folge","en":"consequence; result","ru":"следствие; последствие","vi":"hậu quả","fa":"نتیجه","examples":[{"de":"Die Folgen seiner Entscheidung waren nicht absehbar.","en":"The consequences of his decision were not foreseeable.","ru":"Последствия его решения было невозможно предвидеть.","vi":"Hậu quả của quyết định của ông là không thể lường trước được.","fa":"عواقب تصمیم او قابل پیش بینی نبود."},{"de":"Als Folge des Regens wurde das Spiel abgesagt.","en":"As a result of the rain, the game was cancelled.","ru":"Из-за дождя игру отменили.","vi":"Do trời mưa nên trò chơi đã bị hủy.","fa":"در نتیجه باران بازی لغو شد."}]},{"word":"folgen","en":"to follow","ru":"следовать","vi":"theo dõi","fa":"دنبال کنید","examples":[{"de":"Bitte folgen Sie mir, das Büro ist gleich hier.","en":"Please follow me, the office is right here.","ru":"Пожалуйста, следуйте за мной, офис прямо здесь.","vi":"Hãy đi theo tôi, văn phòng ở ngay đây.","fa":"لطفا من را دنبال کنید، دفتر اینجاست."},{"de":"Der Hund folgte seinem Besitzer auf Schritt und Tritt.","en":"The dog followed its owner everywhere.","ru":"Собака следовала за хозяином по пятам.","vi":"Con chó đi theo chủ mọi lúc mọi nơi.","fa":"The dog followed his owner wherever he went."}]},{"word":"folgend","en":"following","ru":"следующий","vi":"theo dõi","fa":"دنبال کردن","examples":[{"de":"Lesen Sie bitte den folgenden Text.","en":"Please read the following text.","ru":"Прочитайте, пожалуйста, следующий текст.","vi":"Xin vui lòng đọc văn bản sau đây.","fa":"لطفا متن زیر را بخوانید."},{"de":"Am folgenden Tag war das Wetter besser.","en":"On the following day the weather was better.","ru":"На следующий день погода была лучше.","vi":"Ngày hôm sau thời tiết tốt hơn.","fa":"روز بعد هوا بهتر بود."},{"de":"Bitte beachten Sie die folgenden Hinweise.","en":"Please note the following instructions.","ru":"Обратите, пожалуйста, внимание на следующие указания.","vi":"Xin vui lòng lưu ý các thông tin sau.","fa":"لطفا به اطلاعات زیر توجه کنید."}]},{"word":"folglich","en":"consequently; therefore","ru":"следовательно; поэтому","vi":"do đó","fa":"در نتیجه","examples":[{"de":"Er war krank und konnte folglich nicht kommen.","en":"He was ill and consequently could not come.","ru":"Он был болен и, следовательно, не смог прийти.","vi":"Anh ấy bị ốm nên không thể đến được.","fa":"او مریض بود و به همین دلیل نتوانست بیاید."},{"de":"Die Nachfrage stieg, folglich stiegen auch die Preise.","en":"Demand rose, and consequently prices rose too.","ru":"Спрос вырос, следовательно, выросли и цены.","vi":"Nhu cầu tăng lên, và kết quả là giá cả cũng tăng theo.","fa":"تقاضا افزایش یافت و در نتیجه قیمت ها نیز افزایش یافت."}]},{"word":"der Follower","en":"a follower on a social network","ru":"подписчик (в соцсети)","vi":"người theo dõi","fa":"the follower","examples":[{"de":"Bekannte Menschen haben oft viele Follower.","en":"Famous people often have lots of followers.","ru":"У знаменитостей часто много подписчиков.","vi":"Người nổi tiếng thường có nhiều người theo dõi.","fa":"افراد شناخته شده اغلب فالوورهای زیادی دارند."},{"de":"Sie hat über zehntausend Follower auf ihrem Profil.","en":"She has over ten thousand followers on her profile.","ru":"У неё в профиле более десяти тысяч подписчиков.","vi":"Cô có hơn mười nghìn người theo dõi trên trang cá nhân của mình.","fa":"او بیش از ده هزار دنبال کننده در پروفایل خود دارد."},{"de":"Mit jedem Video bekommt der Kanal neue Follower.","en":"With every video the channel gains new followers.","ru":"С каждым видео канал набирает новых подписчиков.","vi":"Kênh có được người theo dõi mới sau mỗi video.","fa":"این کانال با هر ویدیو فالوورهای جدیدی پیدا می کند."}]},{"word":"fordern","en":"to demand","ru":"требовать","vi":"nhu cầu","fa":"تقاضا","examples":[{"de":"Die Mitarbeiter fordern höhere Löhne.","en":"The employees are demanding higher wages.","ru":"Сотрудники требуют повышения зарплаты.","vi":"Các nhân viên đang đòi hỏi mức lương cao hơn.","fa":"کارگران خواستار افزایش دستمزد هستند."},{"de":"Der Lehrer fordert von uns pünktliche Hausaufgaben.","en":"The teacher demands that we hand in homework on time.","ru":"Учитель требует от нас сдавать домашние задания вовремя.","vi":"Giáo viên yêu cầu chúng tôi làm bài tập về nhà đúng giờ.","fa":"معلم از ما می خواهد که تکالیف خود را به موقع انجام دهیم."}]},{"word":"fördern","en":"to promote, support","ru":"поддерживать, способствовать","vi":"thúc đẩy","fa":"ترویج کنند","examples":[{"de":"Sport fördert die Gesundheit von Kindern.","en":"Sport promotes children's health.","ru":"Спорт способствует здоровью детей.","vi":"Thể thao tăng cường sức khỏe cho trẻ em.","fa":"ورزش باعث ارتقای سلامت کودکان می شود."},{"de":"Der Staat fördert junge Künstler mit Stipendien.","en":"The state supports young artists with scholarships.","ru":"Государство поддерживает молодых художников стипендиями.","vi":"Nhà nước hỗ trợ nghệ sĩ trẻ bằng học bổng.","fa":"دولت از هنرمندان جوان با بورسیه حمایت می کند."}]},{"word":"die Form","en":"shape, form","ru":"форма","vi":"hình dạng","fa":"شکل","examples":[{"de":"Der Kuchen hat die Form eines Herzens.","en":"The cake has the shape of a heart.","ru":"Торт имеет форму сердца.","vi":"Chiếc bánh có hình trái tim.","fa":"شکل کیک شبیه قلب است."},{"de":"In welcher Form möchten Sie die Information bekommen?","en":"In what form would you like to receive the information?","ru":"В какой форме вы хотите получить информацию?","vi":"Bạn muốn nhận thông tin dưới hình thức nào?","fa":"به چه شکلی می خواهید اطلاعات را دریافت کنید؟"}]},{"word":"das Formular","en":"form (document)","ru":"бланк, формуляр","vi":"hình thức","fa":"فرم","examples":[{"de":"Bitte füllen Sie dieses Formular vollständig aus.","en":"Please fill out this form completely.","ru":"Пожалуйста, заполните этот бланк полностью.","vi":"Vui lòng điền đầy đủ vào mẫu này.","fa":"لطفا این فرم را به طور کامل پر کنید."},{"de":"Das Formular für den Antrag finden Sie auf der Webseite.","en":"You can find the application form on the website.","ru":"Бланк заявления вы найдёте на сайте.","vi":"Mẫu đơn có thể được tìm thấy trên trang web.","fa":"فرم درخواست را می توان در وب سایت یافت."}]},{"word":"die Forschung","en":"research","ru":"исследование","vi":"nghiên cứu","fa":"تحقیق","examples":[{"de":"Die Forschung im Bereich der Medizin macht große Fortschritte.","en":"Research in the field of medicine is making great progress.","ru":"Исследования в области медицины делают большие успехи.","vi":"Nghiên cứu trong lĩnh vực y học đang có những tiến bộ vượt bậc.","fa":"تحقیقات در زمینه پزشکی پیشرفت زیادی دارد."},{"de":"Sie arbeitet an der Universität in der Forschung.","en":"She works in research at the university.","ru":"Она работает в сфере исследований в университете.","vi":"Cô ấy làm việc nghiên cứu ở trường đại học.","fa":"او در دانشگاه کار تحقیقاتی می کند."}]},{"word":"die Fortbildung","en":"further training","ru":"повышение квалификации","vi":"việc đào tạo","fa":"آموزش","examples":[{"de":"Meine Firma bietet regelmäßig Fortbildungen für Mitarbeiter an.","en":"My company regularly offers further training for employees.","ru":"Моя компания регулярно предлагает курсы повышения квалификации для сотрудников.","vi":"Công ty của tôi thường xuyên tổ chức đào tạo cho nhân viên.","fa":"شرکت من به طور منظم برای کارمندان آموزش ارائه می دهد."},{"de":"Nächste Woche nehme ich an einer Fortbildung zum Thema Kommunikation teil.","en":"Next week I'm taking part in a training course on communication.","ru":"На следующей неделе я участвую в курсе повышения квалификации по теме коммуникации.","vi":"Tuần tới tôi sẽ tham gia một khóa đào tạo về giao tiếp.","fa":"هفته آینده در یک دوره آموزشی در زمینه ارتباطات شرکت خواهم کرد."}]},{"word":"der Fortschritt","en":"progress","ru":"прогресс, успех","vi":"sự tiến bộ","fa":"پیشرفت","examples":[{"de":"Der Patient macht gute Fortschritte nach der Operation.","en":"The patient is making good progress after the operation.","ru":"Пациент делает хорошие успехи после операции.","vi":"Bệnh nhân đang tiến triển tốt sau phẫu thuật.","fa":"بیمار پس از جراحی پیشرفت خوبی دارد."},{"de":"In den letzten Jahren gab es großen technischen Fortschritt.","en":"In recent years there has been great technical progress.","ru":"За последние годы произошёл большой технический прогресс.","vi":"Đã có tiến bộ kỹ thuật lớn trong những năm gần đây.","fa":"در سال های اخیر پیشرفت های فنی زیادی داشته است."}]},{"word":"fortsetzen","en":"to continue","ru":"продолжать","vi":"tiếp tục","fa":"ادامه","examples":[{"de":"Wir setzen die Besprechung morgen früh fort.","en":"We will continue the meeting tomorrow morning.","ru":"Мы продолжим совещание завтра утром.","vi":"Chúng ta sẽ tiếp tục cuộc họp vào sáng mai.","fa":"فردا صبح جلسه را ادامه می دهیم."},{"de":"Nach der Pause setzte der Lehrer den Unterricht fort.","en":"After the break the teacher continued the lesson.","ru":"После перерыва учитель продолжил урок.","vi":"Sau giờ giải lao, giáo viên tiếp tục bài học.","fa":"بعد از استراحت، معلم درس را ادامه داد."}]},{"word":"die Fortsetzung","en":"continuation, sequel","ru":"продолжение; сиквел","vi":"phần tiếp theo","fa":"the sequel","examples":[{"de":"Die Fortsetzung des Films kommt nächstes Jahr ins Kino.","en":"The sequel to the film comes to the cinema next year.","ru":"Продолжение фильма выйдет в кино в следующем году.","vi":"Phần tiếp theo của bộ phim sẽ được phát hành vào năm tới.","fa":"دنباله این فیلم سال آینده اکران خواهد شد."},{"de":"Am Ende der Folge stand: Fortsetzung folgt.","en":"At the end of the episode it said: to be continued.","ru":"В конце серии было написано: продолжение следует.","vi":"Cuối tập phim có ghi: Còn tiếp.","fa":"در پایان قسمت گفته شد: ادامه دارد."},{"de":"Ich freue mich schon auf die Fortsetzung der Geschichte.","en":"I am already looking forward to the continuation of the story.","ru":"Я уже с нетерпением жду продолжения истории.","vi":"Tôi rất mong chờ sự tiếp tục của câu chuyện.","fa":"بی صبرانه منتظر ادامه داستان هستم."}]},{"word":"das Forum","en":"forum","ru":"форум","vi":"diễn đàn","fa":"انجمن","examples":[{"de":"Im Internetforum tauschen sich viele Nutzer über das Thema aus.","en":"In the internet forum many users exchange views on the topic.","ru":"На интернет-форуме многие пользователи обмениваются мнениями по этой теме.","vi":"Nhiều người dùng trao đổi ý kiến về chủ đề này trên diễn đàn Internet.","fa":"بسیاری از کاربران در مورد این موضوع در انجمن اینترنت تبادل نظر می کنند."},{"de":"Ich habe die Antwort auf meine Frage in einem Forum gefunden.","en":"I found the answer to my question in a forum.","ru":"Я нашёл ответ на свой вопрос на форуме.","vi":"Tôi tìm thấy câu trả lời cho câu hỏi của tôi trong một diễn đàn.","fa":"جواب سوالم را در انجمن پیدا کردم."}]},{"word":"der Fotograf","en":"photographer","ru":"фотограф","vi":"nhiếp ảnh gia","fa":"the photographer","examples":[{"de":"Der Fotograf machte schöne Bilder von der Hochzeit.","en":"The photographer took lovely pictures of the wedding.","ru":"Фотограф сделал красивые снимки со свадьбы.","vi":"Nhiếp ảnh gia đã chụp được những bức ảnh đẹp trong đám cưới.","fa":"عکاس عکس های زیبایی از مراسم عروسی گرفت."},{"de":"Mein Freund möchte Fotograf werden.","en":"My friend wants to become a photographer.","ru":"Мой друг хочет стать фотографом.","vi":"Bạn tôi muốn trở thành một nhiếp ảnh gia.","fa":"دوست من می خواهد عکاس شود."},{"de":"Der Fotograf bat uns, ruhig zu stehen.","en":"The photographer asked us to stand still.","ru":"Фотограф попросил нас стоять спокойно.","vi":"Nhiếp ảnh gia yêu cầu chúng tôi đứng yên.","fa":"عکاس از ما خواست که بی حرکت بایستیم."}]},{"word":"die Fotografie","en":"photograph, photography","ru":"фотография; фотоискусство","vi":"nhiếp ảnh","fa":"عکاسی","examples":[{"de":"An der Wand hängt eine alte Fotografie meiner Großeltern.","en":"On the wall hangs an old photograph of my grandparents.","ru":"На стене висит старая фотография моих бабушки и дедушки.","vi":"Có một bức ảnh cũ của ông bà tôi treo trên tường.","fa":"یک عکس قدیمی از پدربزرگ و مادربزرگم به دیوار آویزان است."},{"de":"Sie interessiert sich sehr für Fotografie.","en":"She is very interested in photography.","ru":"Она очень интересуется фотографией.","vi":"Cô ấy rất quan tâm đến nhiếp ảnh.","fa":"او علاقه زیادی به عکاسی دارد."},{"de":"Die Fotografie zeigt eine Stadt bei Nacht.","en":"The photograph shows a city at night.","ru":"На фотографии изображён город ночью.","vi":"Bức ảnh cho thấy một thành phố về đêm.","fa":"عکس شهری در شب را نشان می دهد."}]},{"word":"fotografieren","en":"to photograph","ru":"фотографировать","vi":"bức ảnh","fa":"عکس","examples":[{"de":"Er fotografiert gern alte Gebäude in der Stadt.","en":"He likes to photograph old buildings in the city.","ru":"Он любит фотографировать старые здания в городе.","vi":"Anh ấy thích chụp ảnh những tòa nhà cổ trong thành phố.","fa":"او از عکاسی از ساختمان های قدیمی شهر لذت می برد."},{"de":"Darf ich Sie kurz fotografieren?","en":"May I take a quick photo of you?","ru":"Можно я вас сфотографирую?","vi":"Tôi có thể chụp ảnh nhanh cho bạn được không?","fa":"میتونم سریع ازت عکس بگیرم؟"}]},{"word":"fragen","en":"to ask","ru":"спрашивать","vi":"hỏi","fa":"بپرسید","examples":[{"de":"Darf ich dich etwas fragen?","en":"May I ask you something?","ru":"Можно тебя кое о чём спросить?","vi":"Tôi có thể hỏi bạn một điều được không?","fa":"میتونم یه چیزی بپرسم؟"},{"de":"Er hat mich nach dem Weg zum Bahnhof gefragt.","en":"He asked me for directions to the train station.","ru":"Он спросил меня, как пройти к вокзалу.","vi":"Anh ấy hỏi tôi đường đến ga xe lửa.","fa":"او از من برای رسیدن به ایستگاه قطار راهنمایی خواست."}]},{"word":"die Frau","en":"woman; wife","ru":"женщина; жена","vi":"người phụ nữ","fa":"زن","examples":[{"de":"Die Frau neben mir liest ein spannendes Buch.","en":"The woman next to me is reading an exciting book.","ru":"Женщина рядом со мной читает увлекательную книгу.","vi":"Người phụ nữ bên cạnh tôi đang đọc một cuốn sách thú vị.","fa":"زن کنار من در حال خواندن یک کتاب هیجان انگیز است."},{"de":"Er stellte mir seine Frau vor.","en":"He introduced me to his wife.","ru":"Он познакомил меня со своей женой.","vi":"Anh giới thiệu tôi với vợ anh.","fa":"او مرا به همسرش معرفی کرد."}]},{"word":"frech","en":"cheeky","ru":"дерзкий, наглый","vi":"táo bạo","fa":"گستاخ","examples":[{"de":"Der kleine Junge war frech zu seiner Lehrerin.","en":"The little boy was cheeky to his teacher.","ru":"Маленький мальчик был дерзок со своей учительницей.","vi":"Cậu bé rất hỗn láo với giáo viên của mình.","fa":"پسر کوچولو با معلمش گستاخ بود."},{"de":"Sei nicht so frech, das ist unhöflich!","en":"Don't be so cheeky, that's rude!","ru":"Не будь таким дерзким, это невежливо!","vi":"Đừng táo bạo như vậy, thật thô lỗ!","fa":"اینقدر گستاخ نباش، بی ادبی است!"}]},{"word":"frei","en":"free","ru":"свободный","vi":"miễn phí","fa":"رایگان","examples":[{"de":"Ist dieser Platz noch frei?","en":"Is this seat still free?","ru":"Это место ещё свободно?","vi":"Chỗ này còn trống không?","fa":"آیا این فضا هنوز موجود است؟"},{"de":"Morgen habe ich endlich einen freien Tag.","en":"Tomorrow I finally have a day off.","ru":"Завтра у меня наконец-то выходной.","vi":"Cuối cùng ngày mai tôi cũng có một ngày nghỉ.","fa":"فردا بالاخره یک روز تعطیل دارم."}]},{"word":"die Freiheit","en":"freedom","ru":"свобода","vi":"sự tự do","fa":"آزادی","examples":[{"de":"Die Freiheit der Presse ist sehr wichtig.","en":"Freedom of the press is very important.","ru":"Свобода прессы очень важна.","vi":"Tự do báo chí là rất quan trọng.","fa":"آزادی مطبوعات بسیار مهم است."},{"de":"Nach dem Studium genoss sie ihre neue Freiheit.","en":"After graduating she enjoyed her new freedom.","ru":"После учёбы она наслаждалась своей новой свободой.","vi":"Sau khi hoàn thành việc học, cô tận hưởng sự tự do mới của mình.","fa":"پس از اتمام تحصیلات، او از آزادی جدید خود لذت برد."}]},{"word":"freiwillig","en":"voluntary","ru":"добровольный","vi":"tự nguyện","fa":"داوطلبانه","examples":[{"de":"Die Teilnahme an dem Kurs ist freiwillig.","en":"Participation in the course is voluntary.","ru":"Участие в курсе является добровольным.","vi":"Việc tham gia khóa học là tự nguyện.","fa":"شرکت در دوره داوطلبانه است."},{"de":"Er arbeitet freiwillig in einem Tierheim.","en":"He works voluntarily at an animal shelter.","ru":"Он добровольно работает в приюте для животных.","vi":"Anh ấy làm tình nguyện viên tại một nơi trú ẩn động vật.","fa":"او در یک پناهگاه حیوانات داوطلب می شود."}]},{"word":"die Freiwillige","en":"volunteer (female)","ru":"доброволец, волонтёр (женщина)","vi":"tình nguyện viên","fa":"the volunteer","examples":[{"de":"Die Freiwillige half den ganzen Tag im Tierheim.","en":"The volunteer helped at the animal shelter all day.","ru":"Волонтёрка целый день помогала в приюте для животных.","vi":"Tình nguyện viên đã giúp đỡ ở nơi trú ẩn động vật cả ngày.","fa":"این داوطلب تمام روز در پناهگاه حیوانات کمک کرد."},{"de":"Wir suchen noch Freiwillige für das Festival.","en":"We are still looking for volunteers for the festival.","ru":"Мы ещё ищем волонтёров для фестиваля.","vi":"Chúng tôi vẫn đang tìm kiếm tình nguyện viên cho lễ hội.","fa":"ما همچنان به دنبال داوطلب برای جشنواره هستیم."},{"de":"Als Freiwillige unterstützt sie geflüchtete Familien.","en":"As a volunteer she supports refugee families.","ru":"Как волонтёр она поддерживает семьи беженцев.","vi":"Là một tình nguyện viên, cô hỗ trợ các gia đình tị nạn.","fa":"او به عنوان یک داوطلب از خانواده های پناهنده حمایت می کند."}]},{"word":"fremd","en":"foreign, strange","ru":"чужой, незнакомый","vi":"nước ngoài","fa":"خارجی","examples":[{"de":"In einer fremden Stadt fühlt man sich am Anfang oft unsicher.","en":"In a foreign city you often feel unsure at first.","ru":"В незнакомом городе поначалу часто чувствуешь себя неуверенно.","vi":"Ở một thành phố xa lạ, ban đầu bạn thường cảm thấy không an toàn.","fa":"در یک شهر خارجی اغلب در ابتدا احساس ناامنی می کنید."},{"de":"Ein fremder Mann fragte mich nach der Uhrzeit.","en":"A stranger asked me for the time.","ru":"Незнакомый мужчина спросил меня, который час.","vi":"Một người đàn ông lạ hỏi tôi thời gian.","fa":"مرد غریبی از من ساعت را پرسید."}]},{"word":"die Fremdsprache","en":"foreign language","ru":"иностранный язык","vi":"ngoại ngữ","fa":"the foreign language","examples":[{"de":"Englisch war die erste Fremdsprache, die ich gelernt habe.","en":"English was the first foreign language I learnt.","ru":"Английский был первым иностранным языком, который я выучил.","vi":"Tiếng Anh là ngoại ngữ đầu tiên tôi học.","fa":"انگلیسی اولین زبان خارجی بود که یاد گرفتم."},{"de":"Für diesen Job brauchst du mindestens eine Fremdsprache.","en":"For this job you need at least one foreign language.","ru":"Для этой работы тебе нужен хотя бы один иностранный язык.","vi":"Đối với công việc này bạn cần ít nhất một ngoại ngữ.","fa":"برای این شغل حداقل به یک زبان خارجی نیاز دارید."},{"de":"Sie spricht drei Fremdsprachen fließend.","en":"She speaks three foreign languages fluently.","ru":"Она свободно говорит на трёх иностранных языках.","vi":"Cô nói trôi chảy ba ngoại ngữ.","fa":"او سه زبان خارجی را روان صحبت می کند."}]},{"word":"die Frequenz","en":"frequency","ru":"частота","vi":"tần số","fa":"فرکانس","examples":[{"de":"Die Frequenz gibt an, wie oft eine Welle pro Sekunde schwingt.","en":"The frequency indicates how often a wave oscillates per second.","ru":"Частота показывает, сколько раз волна колеблется в секунду.","vi":"Tần số cho biết sóng dao động bao nhiêu lần trong một giây.","fa":"فرکانس نشان می دهد که یک موج چند بار در ثانیه نوسان می کند."},{"de":"Hohe Töne haben eine hohe Frequenz.","en":"High notes have a high frequency.","ru":"У высоких звуков высокая частота.","vi":"Âm cao có tần số cao.","fa":"زنگ های بالا فرکانس بالایی دارند."},{"de":"Die Frequenz wird in Hertz gemessen.","en":"Frequency is measured in hertz.","ru":"Частоту измеряют в герцах.","vi":"Tần số được đo bằng hertz.","fa":"فرکانس بر حسب هرتز اندازه گیری می شود."}]},{"word":"fressen","en":"to eat (animals)","ru":"есть, жрать (о животных)","vi":"ăn","fa":"خوردن","examples":[{"de":"Die Katze frisst nur zweimal am Tag.","en":"The cat only eats twice a day.","ru":"Кошка ест только два раза в день.","vi":"Con mèo chỉ ăn hai lần một ngày.","fa":"گربه فقط دو بار در روز غذا می خورد."},{"de":"Der Hund frisst sein Futter immer sehr schnell.","en":"The dog always eats its food very fast.","ru":"Собака всегда очень быстро съедает свой корм.","vi":"Con chó luôn ăn thức ăn của mình rất nhanh.","fa":"سگ همیشه غذایش را خیلی سریع می خورد."}]},{"word":"die Freude","en":"joy, pleasure","ru":"радость, удовольствие","vi":"niềm vui","fa":"the joy","examples":[{"de":"Es ist mir eine große Freude, Sie kennenzulernen.","en":"It is a great pleasure to meet you.","ru":"Для меня большая радость познакомиться с вами.","vi":"Tôi rất vui được gặp bạn.","fa":"از آشنایی با شما بسیار خوشحالم."},{"de":"Die Kinder konnten ihre Freude kaum verbergen.","en":"The children could hardly hide their joy.","ru":"Дети едва могли скрыть свою радость.","vi":"Các em khó có thể kìm được niềm vui.","fa":"بچه ها به سختی می توانستند شادی خود را حفظ کنند."},{"de":"Mit großer Freude haben wir Ihre Einladung angenommen.","en":"We accepted your invitation with great pleasure.","ru":"С большой радостью мы приняли ваше приглашение.","vi":"Chúng tôi rất vui mừng khi nhận lời mời của bạn.","fa":"با کمال خرسندی دعوت شما را پذیرفتیم."}]},{"word":"der Freund","en":"friend; boyfriend","ru":"друг; парень (бойфренд)","vi":"người bạn","fa":"دوست","examples":[{"de":"Er ist mein bester Freund seit der Grundschule.","en":"He has been my best friend since elementary school.","ru":"Он мой лучший друг с начальной школы.","vi":"Anh ấy là bạn thân nhất của tôi từ hồi tiểu học.","fa":"او از دوران دبستان بهترین دوست من بود."},{"de":"Sie hat mir ihren neuen Freund vorgestellt.","en":"She introduced me to her new boyfriend.","ru":"Она познакомила меня со своим новым парнем.","vi":"Cô ấy giới thiệu tôi với bạn trai mới của cô ấy.","fa":"او مرا به دوست پسر جدیدش معرفی کرد."}]},{"word":"die Freundschaft","en":"friendship","ru":"дружба","vi":"tình bạn","fa":"دوستی","examples":[{"de":"Unsere Freundschaft hält schon seit zwanzig Jahren.","en":"Our friendship has lasted for twenty years already.","ru":"Наша дружба длится уже двадцать лет.","vi":"Tình bạn của chúng tôi đã kéo dài được hai mươi năm.","fa":"دوستی ما بیست سال است که ادامه دارد."},{"de":"Eine echte Freundschaft übersteht auch schwierige Zeiten.","en":"A true friendship survives difficult times too.","ru":"Настоящая дружба выдерживает и трудные времена.","vi":"Một tình bạn thực sự tồn tại ngay cả những thời điểm khó khăn.","fa":"یک دوستی واقعی حتی در مواقع سخت هم زنده می ماند."},{"de":"Aus der Zusammenarbeit ist eine enge Freundschaft entstanden.","en":"A close friendship grew out of the collaboration.","ru":"Из совместной работы возникла тесная дружба.","vi":"Sự hợp tác đã dẫn đến một tình bạn thân thiết.","fa":"این همکاری منجر به یک دوستی نزدیک شد."}]},{"word":"die Freundschaftsanfrage","en":"a friend request on a social network","ru":"запрос в друзья (в социальной сети)","vi":"yêu cầu kết bạn","fa":"درخواست دوستی","examples":[{"de":"Man kann Freundschaftsanfragen versenden und erhalten.","en":"You can send and receive friend requests.","ru":"Можно отправлять и получать запросы в друзья.","vi":"Bạn có thể gửi và nhận yêu cầu kết bạn.","fa":"می توانید درخواست های دوستی را ارسال و دریافت کنید."},{"de":"Ich habe heute eine Freundschaftsanfrage von einem Kollegen bekommen.","en":"I received a friend request from a colleague today.","ru":"Сегодня я получил запрос в друзья от коллеги.","vi":"Hôm nay tôi nhận được lời mời kết bạn từ một đồng nghiệp.","fa":"امروز از یکی از همکاران درخواست دوستی دریافت کردم."},{"de":"Sie hat seine Freundschaftsanfrage einfach ignoriert.","en":"She simply ignored his friend request.","ru":"Она просто проигнорировала его запрос в друзья.","vi":"Cô chỉ đơn giản là phớt lờ lời mời kết bạn của anh.","fa":"او به سادگی درخواست دوستی او را نادیده گرفت."}]},{"word":"der Friede","en":"peace","ru":"мир","vi":"hòa bình","fa":"صلح","examples":[{"de":"Nach dem Krieg wünschten sich alle Frieden.","en":"After the war everyone wished for peace.","ru":"После войны все желали мира.","vi":"Sau chiến tranh, mọi người đều mong muốn hòa bình.","fa":"بعد از جنگ همه خواهان صلح بودند."},{"de":"Die beiden Länder leben seit Jahrzehnten in Frieden.","en":"The two countries have lived in peace for decades.","ru":"Обе страны живут в мире уже несколько десятилетий.","vi":"Hai nước đã chung sống hòa bình trong nhiều thập kỷ.","fa":"دو کشور ده ها سال در صلح زندگی کرده اند."}]},{"word":"frieren","en":"to freeze, be cold","ru":"мёрзнуть","vi":"đóng băng","fa":"منجمد کردن","examples":[{"de":"Ich friere, kannst du bitte das Fenster schließen?","en":"I'm cold, can you please close the window?","ru":"Мне холодно, можешь закрыть окно?","vi":"Tôi lạnh cóng, bạn có thể đóng cửa sổ được không?","fa":"دارم یخ میزنم، میشه لطفا پنجره رو ببندی؟"},{"de":"Ohne Jacke friert man im Winter schnell.","en":"Without a jacket you freeze quickly in winter.","ru":"Без куртки зимой быстро замерзаешь.","vi":"Không có áo khoác bạn sẽ nhanh chóng bị lạnh vào mùa đông.","fa":"بدون ژاکت در زمستان به سرعت سرد می شوید."}]},{"word":"frisch","en":"fresh","ru":"свежий","vi":"tươi","fa":"تازه","examples":[{"de":"Der Fisch auf dem Markt ist heute besonders frisch.","en":"The fish at the market is especially fresh today.","ru":"Рыба на рынке сегодня особенно свежая.","vi":"Cá ở chợ hôm nay đặc biệt tươi ngon.","fa":"ماهی در بازار امروز به خصوص تازه است."},{"de":"Ich brauche jeden Morgen frische Luft.","en":"I need fresh air every morning.","ru":"Мне каждое утро нужен свежий воздух.","vi":"Tôi cần không khí trong lành mỗi sáng.","fa":"من هر روز صبح به هوای تازه نیاز دارم."}]},{"word":"der Friseur","en":"hairdresser","ru":"парикмахер","vi":"thợ làm tóc","fa":"آرایشگاه","examples":[{"de":"Ich habe morgen einen Termin beim Friseur.","en":"I have an appointment at the hairdresser's tomorrow.","ru":"Завтра у меня запись к парикмахеру.","vi":"Tôi có cuộc hẹn ở tiệm làm tóc vào ngày mai.","fa":"فردا قرار آرایشگاه دارم."},{"de":"Der Friseur hat mir die Haare viel zu kurz geschnitten.","en":"The hairdresser cut my hair far too short.","ru":"Парикмахер подстриг меня слишком коротко.","vi":"Thợ làm tóc đã cắt tóc của tôi quá ngắn.","fa":"آرایشگر موهایم را خیلی کوتاه کرد."}]},{"word":"der Frisör","en":"hairdresser, barber (variant spelling)","ru":"парикмахер (вариант написания)","vi":"thợ làm tóc","fa":"آرایشگاه","examples":[{"de":"Der Frisör um die Ecke ist sehr günstig.","en":"The hairdresser round the corner is very cheap.","ru":"Парикмахер за углом очень недорогой.","vi":"Tiệm làm tóc quanh góc rất rẻ.","fa":"آرایشگاه گوشه ای بسیار ارزان است."},{"de":"Ich habe beim Frisör einen Termin für Freitag.","en":"I have an appointment at the hairdresser's for Friday.","ru":"У меня запись к парикмахеру на пятницу.","vi":"Tôi có cuộc hẹn ở tiệm làm tóc vào thứ Sáu.","fa":"برای جمعه وقت آرایشگاه دارم."},{"de":"Mein Frisör schneidet die Haare immer perfekt.","en":"My hairdresser always cuts my hair perfectly.","ru":"Мой парикмахер всегда идеально стрижёт волосы.","vi":"Thợ làm tóc của tôi luôn cắt tóc cho tôi một cách hoàn hảo.","fa":"آرایشگر من همیشه موهایم را عالی کوتاه می کند."}]},{"word":"die Frist","en":"deadline","ru":"срок","vi":"thời hạn","fa":"مهلت","examples":[{"de":"Die Frist für die Anmeldung endet am Freitag.","en":"The deadline for registration ends on Friday.","ru":"Срок регистрации заканчивается в пятницу.","vi":"Hạn chót đăng ký kết thúc vào thứ Sáu.","fa":"مهلت ثبت نام روز جمعه به پایان می رسد."},{"de":"Wir müssen die Frist unbedingt einhalten.","en":"We absolutely have to meet the deadline.","ru":"Нам обязательно нужно уложиться в срок.","vi":"Chúng ta nhất định phải đáp ứng đúng thời hạn.","fa":"ما قطعا باید ضرب الاجل را رعایت کنیم."}]},{"word":"fristgerecht","en":"on time, within the deadline","ru":"в срок, своевременно","vi":"đúng giờ","fa":"به موقع","examples":[{"de":"Bitte zahlen Sie die Rechnung fristgerecht.","en":"Please pay the bill within the deadline.","ru":"Оплатите, пожалуйста, счёт в срок.","vi":"Vui lòng thanh toán hóa đơn đúng hạn.","fa":"لطفا فاکتور را به موقع پرداخت کنید."},{"de":"Der Antrag wurde fristgerecht eingereicht.","en":"The application was submitted on time.","ru":"Заявка была подана вовремя.","vi":"Đơn đăng ký đã được nộp đúng thời hạn.","fa":"درخواست به موقع ارسال شد."},{"de":"Wir haben die Kündigung fristgerecht erhalten.","en":"We received the notice within the proper period.","ru":"Мы получили уведомление в надлежащий срок.","vi":"Chúng tôi đã nhận được thông báo chấm dứt đúng hạn.","fa":"ما اعلامیه فسخ را به موقع دریافت کردیم."}]},{"word":"fristlos","en":"without notice, summary (dismissal)","ru":"без предупреждения, немедленный (об увольнении)","vi":"không cần thông báo","fa":"بدون اطلاع قبلی","examples":[{"de":"Er wurde fristlos entlassen.","en":"He was dismissed without notice.","ru":"Его уволили без предупреждения.","vi":"Anh ta bị sa thải mà không báo trước.","fa":"او بدون اطلاع قبلی اخراج شد."},{"de":"Eine fristlose Kündigung ist nur in Ausnahmefällen möglich.","en":"Summary dismissal is only possible in exceptional cases.","ru":"Немедленное увольнение возможно только в исключительных случаях.","vi":"Việc chấm dứt mà không cần thông báo chỉ có thể xảy ra trong những trường hợp đặc biệt.","fa":"فسخ بدون اطلاع قبلی فقط در موارد استثنایی امکان پذیر است."},{"de":"Die Firma kündigte ihm fristlos.","en":"The company terminated his contract without notice.","ru":"Фирма расторгла его договор без предупреждения.","vi":"Công ty đã sa thải anh ta mà không báo trước.","fa":"شرکت بدون اطلاع قبلی او را خاتمه داد."}]},{"word":"die Frisur","en":"hairstyle, hairdo","ru":"причёска","vi":"kiểu tóc","fa":"the hairstyle","examples":[{"de":"Deine neue Frisur steht dir wirklich gut.","en":"Your new hairstyle really suits you.","ru":"Твоя новая причёска тебе очень идёт.","vi":"Kiểu tóc mới của bạn thực sự phù hợp với bạn.","fa":"مدل موی جدید شما واقعا به شما می آید."},{"de":"Sie wollte zur Hochzeit eine elegante Frisur.","en":"She wanted an elegant hairstyle for the wedding.","ru":"Она хотела элегантную причёску к свадьбе.","vi":"Cô muốn có một kiểu tóc thanh lịch cho đám cưới của mình.","fa":"او یک مدل موی شیک برای عروسی اش می خواست."},{"de":"Der Wind hat meine ganze Frisur zerstört.","en":"The wind ruined my whole hairdo.","ru":"Ветер испортил мне всю причёску.","vi":"Gió đã phá hủy toàn bộ kiểu tóc của tôi.","fa":"باد تمام مدل موهایم را خراب کرد."}]},{"word":"der Fritze","en":"a chap or fellow (informal, often slightly dismissive)","ru":"тип, мужик, парень (разг., часто слегка пренебрежительно)","vi":"Fritze","fa":"the Fritze","examples":[{"de":"Frag doch den Fritze da vorne, der weiß das bestimmt.","en":"Just ask that chap over there, he's bound to know.","ru":"Спроси вон того типа впереди, он наверняка знает.","vi":"Cứ hỏi Fritze trước đi, chắc chắn anh ấy sẽ biết điều đó.","fa":"فقط از فریتز از قبل بپرسید، او احتمالاً این را می داند."},{"de":"Wer ist denn der Fritze, der da am Eingang steht?","en":"Who's that chap standing by the entrance, then?","ru":"А кто этот тип, что стоит у входа?","vi":"Fritze đang đứng ở lối vào là ai?","fa":"فریتز چه کسی در ورودی ایستاده است؟"},{"de":"Irgendein Fritze hat einfach mein Fahrrad umgeworfen.","en":"Some fellow just knocked my bike over.","ru":"Какой-то мужик просто взял и опрокинул мой велосипед.","vi":"Ai đó vừa tông vào xe đạp của tôi.","fa":"فلانی فقط دوچرخه ام را زد."}]},{"word":"froh","en":"glad, happy","ru":"радостный, довольный","vi":"vui mừng","fa":"خوشحالم","examples":[{"de":"Ich bin froh, dass du wieder gesund bist.","en":"I'm glad that you're healthy again.","ru":"Я рад, что ты снова здоров.","vi":"Tôi mừng vì bạn đã khỏe lại.","fa":"خوشحالم که دوباره سالم هستی"},{"de":"Wir waren alle sehr froh über die gute Nachricht.","en":"We were all very happy about the good news.","ru":"Мы все очень обрадовались хорошей новости.","vi":"Tất cả chúng tôi đều rất vui mừng về tin vui này.","fa":"همه ما از این خبر خوب بسیار خوشحال شدیم."}]},{"word":"fröhlich","en":"cheerful, happy","ru":"весёлый, радостный","vi":"vui vẻ","fa":"شاد","examples":[{"de":"Die Kinder sind heute besonders fröhlich.","en":"The children are particularly cheerful today.","ru":"Дети сегодня особенно весёлые.","vi":"Hôm nay bọn trẻ đặc biệt vui mừng.","fa":"بچه ها امروز خوشحال هستند."},{"de":"Sie sang ein fröhliches Lied.","en":"She sang a cheerful song.","ru":"Она спела весёлую песню.","vi":"Cô hát một bài hát vui vẻ.","fa":"او یک آهنگ شاد خواند."},{"de":"Wir wünschen dir ein fröhliches Fest!","en":"We wish you a merry celebration!","ru":"Желаем вам весёлого праздника!","vi":"Chúng tôi chúc bạn một kỳ nghỉ vui vẻ!","fa":"تعطیلات خوشی را برای شما آرزو می کنیم!"}]},{"word":"die Frucht","en":"fruit","ru":"фрукт, плод","vi":"trái cây","fa":"میوه","examples":[{"de":"Auf dem Markt gibt es viele frische Früchte.","en":"There is a lot of fresh fruit at the market.","ru":"На рынке много свежих фруктов.","vi":"Có rất nhiều trái cây tươi trên thị trường.","fa":"میوه های تازه زیادی در بازار وجود دارد."},{"de":"Diese Frucht schmeckt süß und ein bisschen sauer.","en":"This fruit tastes sweet and a bit sour.","ru":"Этот фрукт на вкус сладкий и немного кислый.","vi":"Loại quả này có vị ngọt và hơi chua.","fa":"طعم این میوه شیرین و کمی ترش است."}]},{"word":"früh","en":"early","ru":"рано","vi":"sớm","fa":"اوایل","examples":[{"de":"Am Montag muss ich sehr früh aufstehen.","en":"On Monday I have to get up very early.","ru":"В понедельник мне нужно встать очень рано.","vi":"Vào thứ Hai tôi phải dậy rất sớm.","fa":"دوشنبه باید خیلی زود بیدار بشم."},{"de":"Wir sind früh am Bahnhof angekommen.","en":"We arrived at the train station early.","ru":"Мы рано приехали на вокзал.","vi":"Chúng tôi đến ga xe lửa sớm.","fa":"زود به ایستگاه قطار رسیدیم."}]},{"word":"früher","en":"earlier, formerly","ru":"раньше, прежде","vi":"trước đó","fa":"زودتر","examples":[{"de":"Früher gab es hier keine U-Bahn.","en":"In the past there was no subway here.","ru":"Раньше здесь не было метро.","vi":"Ở đây từng không có tàu điện ngầm.","fa":"قبلا اینجا مترو نبود."},{"de":"Kannst du morgen etwas früher kommen?","en":"Can you come a bit earlier tomorrow?","ru":"Можешь завтра прийти немного раньше?","vi":"Ngày mai bạn có thể đến sớm hơn một chút được không?","fa":"میشه فردا کمی زودتر بیای؟"}]},{"word":"frühstücken","en":"to have breakfast","ru":"завтракать","vi":"ăn sáng","fa":"صبحانه بخور","examples":[{"de":"Wir frühstücken normalerweise um sieben Uhr.","en":"We usually have breakfast at seven o'clock.","ru":"Мы обычно завтракаем в семь часов.","vi":"Chúng tôi thường ăn sáng lúc bảy giờ.","fa":"ما معمولا ساعت هفت صبحانه می خوریم."},{"de":"Am Wochenende frühstücken wir gerne lange und in Ruhe.","en":"On weekends we like to have a long, relaxed breakfast.","ru":"По выходным мы любим долго и спокойно завтракать.","vi":"Vào cuối tuần, chúng tôi thích có một bữa sáng dài và yên tĩnh.","fa":"آخر هفته ها دوست داریم یک صبحانه طولانی و آرام بخوریم."}]},{"word":"fühlen","en":"to feel","ru":"чувствовать","vi":"cảm thấy","fa":"احساس کنید","examples":[{"de":"Wie fühlst du dich heute?","en":"How do you feel today?","ru":"Как ты себя чувствуешь сегодня?","vi":"Hôm nay bạn cảm thấy thế nào?","fa":"امروز چه احساسی دارید؟"},{"de":"Ich fühle mich in dieser Stadt sehr wohl.","en":"I feel very comfortable in this city.","ru":"Я чувствую себя очень уютно в этом городе.","vi":"Tôi cảm thấy rất thoải mái ở thành phố này.","fa":"من در این شهر احساس راحتی می کنم."}]},{"word":"führen","en":"to lead","ru":"вести, руководить","vi":"chì","fa":"منجر شود","examples":[{"de":"Dieser Weg führt direkt zum See.","en":"This path leads directly to the lake.","ru":"Эта тропа ведёт прямо к озеру.","vi":"Con đường này dẫn thẳng tới hồ.","fa":"این مسیر مستقیماً به دریاچه منتهی می شود."},{"de":"Sie führt seit fünf Jahren die Abteilung.","en":"She has been leading the department for five years.","ru":"Она руководит отделом уже пять лет.","vi":"Cô đã lãnh đạo bộ phận này được 5 năm.","fa":"او پنج سال است که این بخش را رهبری می کند."}]},{"word":"der Führerausweis","en":"driving licence","ru":"водительские права","vi":"giấy phép lái xe","fa":"گواهینامه رانندگی","examples":[{"de":"In der Schweiz braucht man einen Führerausweis, um Auto zu fahren.","en":"In Switzerland you need a driving licence to drive a car.","ru":"В Швейцарии нужны водительские права, чтобы водить машину.","vi":"Ở Thụy Sĩ bạn cần có bằng lái xe để lái ô tô.","fa":"در سوئیس برای رانندگی خودرو به گواهینامه رانندگی نیاز دارید."},{"de":"Er hat seinen Führerausweis letzte Woche gemacht.","en":"He got his driving licence last week.","ru":"Он получил водительские права на прошлой неделе.","vi":"Anh ấy đã lấy được bằng lái xe vào tuần trước.","fa":"او هفته گذشته گواهینامه رانندگی خود را گرفت."}]},{"word":"der Führerschein","en":"driving licence","ru":"водительские права","vi":"giấy phép lái xe","fa":"گواهینامه رانندگی","examples":[{"de":"Ich habe mit achtzehn meinen Führerschein gemacht.","en":"I got my driving licence when I was eighteen.","ru":"Я получил водительские права в восемнадцать лет.","vi":"Tôi có bằng lái xe khi tôi mười tám tuổi.","fa":"در هجده سالگی گواهینامه رانندگی گرفتم."},{"de":"Hast du deinen Führerschein dabei?","en":"Do you have your driving licence with you?","ru":"У тебя с собой водительские права?","vi":"Bạn có mang theo bằng lái xe không?","fa":"آیا گواهینامه رانندگی خود را همراه دارید؟"}]},{"word":"das Führungszeugnis","en":"certificate of good conduct (criminal record check)","ru":"справка о несудимости (о благонадёжности)","vi":"giấy chứng nhận hạnh kiểm tốt","fa":"گواهی حسن رفتار","examples":[{"de":"Für die neue Stelle muss ich ein polizeiliches Führungszeugnis vorlegen.","en":"For the new job I have to submit a police certificate of good conduct.","ru":"Для новой работы мне нужно предоставить справку о несудимости из полиции.","vi":"Đối với vị trí mới, tôi phải xuất trình giấy chứng nhận của cảnh sát.","fa":"برای موقعیت جدید باید گواهی ترخیص پلیس ارائه کنم."},{"de":"Das Führungszeugnis kann man beim Bürgeramt beantragen.","en":"You can apply for the certificate of good conduct at the citizens' office.","ru":"Справку о несудимости можно запросить в муниципальном ведомстве.","vi":"Bạn có thể nộp đơn xin giấy chứng nhận hạnh kiểm tốt tại Văn phòng Đăng ký Công dân.","fa":"می توانید برای دریافت گواهی حسن رفتار به اداره ثبت احوال شهروندان اقدام کنید."},{"de":"Sein Führungszeugnis war völlig sauber.","en":"His certificate of good conduct was completely clean.","ru":"Его справка о несудимости была совершенно чистой.","vi":"Hồ sơ tội phạm của anh ta hoàn toàn trong sạch.","fa":"سابقه کیفری او کاملاً پاک بود."}]},{"word":"das Fundbüro","en":"lost and found office","ru":"бюро находок","vi":"văn phòng thất lạc và tìm thấy","fa":"دفتر گم شده و پیدا شده","examples":[{"de":"Ich habe meinen Regenschirm im Bus vergessen und muss zum Fundbüro gehen.","en":"I left my umbrella on the bus and have to go to the lost and found office.","ru":"Я забыл зонт в автобусе и должен пойти в бюро находок.","vi":"Tôi để quên ô trên xe buýt và phải đến văn phòng thất lạc tài sản.","fa":"چترم را در اتوبوس فراموش کردم و باید به دفتر اموال گمشده بروم."},{"de":"Das Fundbüro am Bahnhof hat meinen Koffer gefunden.","en":"The lost and found office at the station found my suitcase.","ru":"Бюро находок на вокзале нашло мой чемодан.","vi":"Phòng quản lý tài sản thất lạc ở nhà ga đã tìm thấy va li của tôi.","fa":"دفتر اموال گمشده در ایستگاه قطار چمدان مرا پیدا کرد."}]},{"word":"funktionieren","en":"to work, function","ru":"работать, функционировать","vi":"làm việc","fa":"کار کردن","examples":[{"de":"Mein Handy funktioniert seit gestern nicht mehr richtig.","en":"My phone hasn't been working properly since yesterday.","ru":"Мой телефон с вчерашнего дня работает неправильно.","vi":"Điện thoại di động của tôi đã không hoạt động bình thường kể từ hôm qua.","fa":"تلفن همراه من از دیروز درست کار نمی کند."},{"de":"Die neue App funktioniert wirklich gut.","en":"The new app really works well.","ru":"Новое приложение работает действительно хорошо.","vi":"Ứng dụng mới hoạt động thực sự tốt.","fa":"برنامه جدید واقعاً خوب کار می کند."}]},{"word":"für","en":"for","ru":"для, за","vi":"cho","fa":"برای","examples":[{"de":"Dieses Geschenk ist für dich.","en":"This gift is for you.","ru":"Этот подарок для тебя.","vi":"Món quà này là dành cho bạn.","fa":"این هدیه برای شماست."},{"de":"Ich habe mich für den neuen Job entschieden.","en":"I decided on the new job.","ru":"Я решил в пользу новой работы.","vi":"Tôi đã quyết định về công việc mới.","fa":"من برای کار جدید تصمیم گرفته ام."}]},{"word":"Für mich ist … besonders wichtig","en":"For me, … is especially important (priority)","ru":"Для меня особенно важно … (приоритет)","vi":"Với tôi,… đặc biệt quan trọng","fa":"برای من، … بسیار مهم است","examples":[{"de":"Für mich ist die Familie besonders wichtig.","en":"For me, family is especially important.","ru":"Для меня особенно важна семья.","vi":"Với tôi, gia đình đặc biệt quan trọng.","fa":"برای من خانواده اهمیت ویژه ای دارد."}]},{"word":"furchtbar","en":"terrible, awful","ru":"ужасный","vi":"khủng khiếp","fa":"وحشتناک","examples":[{"de":"Das Wetter heute ist furchtbar kalt.","en":"The weather today is terribly cold.","ru":"Погода сегодня ужасно холодная.","vi":"Thời tiết hôm nay lạnh khủng khiếp.","fa":"هوا امروز به طرز وحشتناکی سرد است."},{"de":"Es tut mir furchtbar leid, dass ich zu spät bin.","en":"I'm terribly sorry that I'm late.","ru":"Мне ужасно жаль, что я опоздал.","vi":"Tôi vô cùng xin lỗi tôi đến muộn.","fa":"خیلی متاسفم که دیر اومدم"}]},{"word":"fürchten","en":"to fear, to be afraid of","ru":"бояться, опасаться","vi":"nỗi sợ hãi","fa":"ترس","examples":[{"de":"Ich fürchte, wir kommen zu spät.","en":"I'm afraid we'll be too late.","ru":"Боюсь, мы опоздаем.","vi":"Tôi sợ chúng ta đã quá muộn.","fa":"میترسم خیلی دیر اومدیم"},{"de":"Sie fürchtet sich vor Spinnen.","en":"She is afraid of spiders.","ru":"Она боится пауков.","vi":"Cô ấy sợ nhện.","fa":"او از عنکبوت می ترسد."},{"de":"Er fürchtete um seinen Arbeitsplatz.","en":"He feared for his job.","ru":"Он опасался за свою работу.","vi":"Anh lo sợ cho công việc của mình.","fa":"از شغلش می ترسید."}]},{"word":"der Fuß","en":"foot","ru":"нога, стопа","vi":"bàn chân","fa":"پا","examples":[{"de":"Ich habe mir gestern beim Sport am Fuß verletzt.","en":"I injured my foot yesterday while doing sports.","ru":"Вчера во время спорта я повредил ногу.","vi":"Tôi bị thương ở chân khi chơi thể thao ngày hôm qua.","fa":"دیروز در حین ورزش پایم آسیب دید."},{"de":"Wir gehen jeden Tag zu Fuß zur Arbeit.","en":"We walk to work every day.","ru":"Мы каждый день ходим на работу пешком.","vi":"Chúng tôi đi bộ đi làm hàng ngày.","fa":"ما هر روز پیاده روی سر کار می رویم."}]},{"word":"der Fußgänger","en":"pedestrian","ru":"пешеход","vi":"người đi bộ","fa":"the pedestrian","examples":[{"de":"Der Fußgänger wartete an der roten Ampel.","en":"The pedestrian waited at the red light.","ru":"Пешеход ждал на красный свет.","vi":"Người đi bộ đang chờ đèn đỏ.","fa":"عابر پیاده پشت چراغ قرمز منتظر بود."},{"de":"Autofahrer müssen auf Fußgänger Rücksicht nehmen.","en":"Drivers have to be considerate of pedestrians.","ru":"Водители должны считаться с пешеходами.","vi":"Người lái xe phải quan tâm đến người đi bộ.","fa":"رانندگان باید مراقب عابران پیاده باشند."},{"de":"Ein Fußgänger überquerte gerade die Straße.","en":"A pedestrian was just crossing the road.","ru":"Пешеход как раз переходил дорогу.","vi":"Một người đi bộ đang băng qua đường.","fa":"یک عابر پیاده در حال عبور از خیابان بود."}]},{"word":"die Fußgängerin","en":"pedestrian (female)","ru":"пешеход (женщина)","vi":"người đi bộ","fa":"the pedestrian","examples":[{"de":"Die Fußgängerin schaute nach links und rechts.","en":"The pedestrian looked left and right.","ru":"Пешеходка посмотрела налево и направо.","vi":"Người đi bộ nhìn trái nhìn phải.","fa":"عابر پیاده به چپ و راست نگاه کرد."},{"de":"Eine Fußgängerin half dem alten Mann über die Straße.","en":"A female pedestrian helped the old man across the road.","ru":"Женщина-пешеход помогла старику перейти дорогу.","vi":"Một người đi bộ đã giúp ông già qua đường.","fa":"عابر پیاده به پیرمرد آن طرف خیابان کمک کرد."},{"de":"Die Fußgängerin trug bei Dunkelheit reflektierende Kleidung.","en":"The pedestrian wore reflective clothing in the dark.","ru":"В темноте пешеходка носила светоотражающую одежду.","vi":"Người đi bộ mặc quần áo phản quang trong bóng tối.","fa":"عابر پیاده در تاریکی لباس انعکاسی به تن داشت."}]},{"word":"die Fußgängerzone","en":"pedestrian zone","ru":"пешеходная зона","vi":"khu vực dành cho người đi bộ","fa":"منطقه عابر پیاده","examples":[{"de":"In der Fußgängerzone dürfen keine Autos fahren.","en":"No cars are allowed to drive in the pedestrian zone.","ru":"В пешеходной зоне запрещено движение автомобилей.","vi":"Ô tô không được phép đi vào khu vực dành cho người đi bộ.","fa":"تردد خودروها در محدوده عابر پیاده ممنوع است."},{"de":"Die Geschäfte in der Fußgängerzone sind samstags gut besucht.","en":"The shops in the pedestrian zone are busy on Saturdays.","ru":"Магазины в пешеходной зоне по субботам хорошо посещаются.","vi":"Các cửa hàng ở khu vực dành cho người đi bộ luôn tấp nập vào ngày thứ Bảy.","fa":"مغازه های منطقه عابر پیاده شنبه ها شلوغ هستند."}]},{"word":"füttern","en":"to feed","ru":"кормить","vi":"cho ăn","fa":"غذا دادن","examples":[{"de":"Bitte füttere die Katze, bevor du zur Schule gehst.","en":"Please feed the cat before you go to school.","ru":"Покорми, пожалуйста, кошку, прежде чем идти в школу.","vi":"Hãy cho mèo ăn trước khi đến trường.","fa":"لطفا قبل از رفتن به مدرسه به گربه غذا بدهید."},{"de":"Man sollte Enten im Park nicht mit Brot füttern.","en":"You shouldn't feed ducks in the park with bread.","ru":"Не стоит кормить уток в парке хлебом.","vi":"Bạn không nên cho vịt ăn bánh mì trong công viên.","fa":"در پارک نباید به اردک ها نان بدهید."}]},{"word":"die Gabel","en":"fork","ru":"вилка","vi":"cái nĩa","fa":"چنگال","examples":[{"de":"Kannst du mir bitte eine Gabel geben?","en":"Can you give me a fork, please?","ru":"Можешь дать мне вилку?","vi":"Bạn có thể vui lòng cho tôi một cái nĩa được không?","fa":"میشه لطفا یک چنگال به من بدهید؟"},{"de":"In manchen Ländern isst man ohne Messer und Gabel.","en":"In some countries people eat without a knife and fork.","ru":"В некоторых странах едят без ножа и вилки.","vi":"Ở một số nước người ta ăn mà không dùng dao và nĩa.","fa":"در برخی کشورها مردم بدون چاقو و چنگال غذا می خورند."}]},{"word":"der Gabelstapler","en":"forklift truck","ru":"вилочный погрузчик","vi":"xe nâng","fa":"the forklift","examples":[{"de":"Im Lager fährt der Mitarbeiter einen Gabelstapler.","en":"In the warehouse the worker drives a forklift truck.","ru":"На складе сотрудник управляет вилочным погрузчиком.","vi":"Nhân viên lái xe nâng trong kho.","fa":"کارمند با لیفتراک در انبار رانندگی می کند."},{"de":"Für den Gabelstapler braucht man einen besonderen Führerschein.","en":"You need a special licence for the forklift truck.","ru":"Для вилочного погрузчика нужны специальные права.","vi":"Bạn cần có giấy phép lái xe đặc biệt để lái xe nâng.","fa":"برای رانندگی لیفتراک به گواهینامه رانندگی ویژه نیاز دارید."},{"de":"Der Gabelstapler hob die schwere Palette mühelos an.","en":"The forklift truck lifted the heavy pallet with ease.","ru":"Вилочный погрузчик легко поднял тяжёлый поддон.","vi":"Xe nâng nâng pallet nặng một cách dễ dàng.","fa":"لیفتراک بدون زحمت پالت سنگین را بلند کرد."}]},{"word":"die Galerie","en":"gallery","ru":"галерея","vi":"phòng trưng bày","fa":"گالری","examples":[{"de":"Am Wochenende besuchen wir eine Galerie mit moderner Kunst.","en":"On the weekend we're visiting a gallery with modern art.","ru":"На выходных мы посетим галерею современного искусства.","vi":"Vào cuối tuần, chúng tôi ghé thăm một phòng trưng bày nghệ thuật hiện đại.","fa":"در آخر هفته از یک گالری با هنر مدرن بازدید می کنیم."},{"de":"Die Galerie zeigt Bilder junger Künstler.","en":"The gallery is showing paintings by young artists.","ru":"Галерея выставляет картины молодых художников.","vi":"Phòng trưng bày trưng bày hình ảnh của các nghệ sĩ trẻ.","fa":"گالری تصاویر هنرمندان جوان را نشان می دهد."}]},{"word":"der Gang","en":"corridor; gear","ru":"коридор; передача (в машине)","vi":"lối đi","fa":"راهرو","examples":[{"de":"Das Klassenzimmer liegt am Ende des Gangs.","en":"The classroom is at the end of the corridor.","ru":"Классная комната находится в конце коридора.","vi":"Lớp học nằm ở cuối hành lang.","fa":"کلاس در انتهای راهرو است."},{"de":"Beim Bergauffahren muss man einen niedrigeren Gang einlegen.","en":"When driving uphill you have to shift into a lower gear.","ru":"При подъёме в гору нужно включить более низкую передачу.","vi":"Khi lái xe lên dốc bạn phải sử dụng số thấp hơn.","fa":"هنگام رانندگی در سربالایی باید از دنده پایین تر استفاده کنید."}]},{"word":"ganz","en":"whole; entirely","ru":"весь; совсем","vi":"hoàn toàn","fa":"به طور کامل","examples":[{"de":"Ich habe den ganzen Kuchen gegessen.","en":"I ate the whole cake.","ru":"Я съел весь торт.","vi":"Tôi đã ăn hết cái bánh.","fa":"من کل کیک رو خوردم"},{"de":"Das Wetter war ganz schön schlecht.","en":"The weather was quite bad.","ru":"Погода была довольно плохой.","vi":"Thời tiết khá tệ.","fa":"هوا خیلی بد بود"}]},{"word":"gar","en":"at all (in negation); done, cooked","ru":"вовсе (при отрицании); готовый (о еде)","vi":"thậm chí","fa":"حتی","examples":[{"de":"Ich habe gar keine Zeit heute.","en":"I have no time at all today.","ru":"У меня сегодня вообще нет времени.","vi":"Hôm nay tôi không có thời gian.","fa":"امروز وقت ندارم"},{"de":"Die Kartoffeln sind noch nicht gar.","en":"The potatoes aren't cooked yet.","ru":"Картофель ещё не готов.","vi":"Khoai tây vẫn chưa chín.","fa":"سیب زمینی ها هنوز پخته نشده اند."}]},{"word":"die Garage","en":"garage","ru":"гараж","vi":"nhà để xe","fa":"گاراژ","examples":[{"de":"Wir parken das Auto in der Garage.","en":"We park the car in the garage.","ru":"Мы паркуем машину в гараже.","vi":"Chúng tôi đậu xe trong gara.","fa":"ماشین را در گاراژ پارک می کنیم."},{"de":"Die Garage ist neben dem Haus.","en":"The garage is next to the house.","ru":"Гараж находится рядом с домом.","vi":"Gara nằm cạnh nhà.","fa":"گاراژ کنار خانه است."}]},{"word":"die Garantie","en":"guarantee, warranty","ru":"гарантия","vi":"sự đảm bảo","fa":"تضمین","examples":[{"de":"Auf dieses Gerät gibt es zwei Jahre Garantie.","en":"There is a two-year guarantee on this device.","ru":"На этот прибор есть двухлетняя гарантия.","vi":"Thiết bị này được bảo hành hai năm.","fa":"این دستگاه دارای دو سال گارانتی می باشد."},{"de":"Die Reparatur ist kostenlos, weil noch Garantie besteht.","en":"The repair is free because the warranty still applies.","ru":"Ремонт бесплатный, потому что ещё действует гарантия.","vi":"Việc sửa chữa là miễn phí vì nó vẫn còn bảo hành.","fa":"تعمیر رایگان است زیرا هنوز تحت گارانتی است."},{"de":"Ohne Garantie würde ich das Produkt nicht kaufen.","en":"Without a warranty I wouldn't buy the product.","ru":"Без гарантии я бы не стал покупать этот товар.","vi":"Tôi sẽ không mua sản phẩm mà không có sự đảm bảo.","fa":"من محصول را بدون گارانتی نمی خرم."}]},{"word":"garantieren","en":"to guarantee","ru":"гарантировать","vi":"đảm bảo","fa":"تضمین می کند","examples":[{"de":"Der Verkäufer garantiert die Qualität des Produkts.","en":"The seller guarantees the quality of the product.","ru":"Продавец гарантирует качество товара.","vi":"Người bán đảm bảo chất lượng của sản phẩm.","fa":"فروشنده کیفیت محصول را تضمین می کند."},{"de":"Ich kann dir nicht garantieren, dass alles klappt.","en":"I can't guarantee you that everything will work out.","ru":"Я не могу гарантировать тебе, что всё получится.","vi":"Tôi không thể đảm bảo với bạn rằng mọi việc sẽ ổn thỏa.","fa":"من نمی توانم به شما تضمین دهم که همه چیز درست می شود."}]},{"word":"die Garderobe","en":"cloakroom, wardrobe","ru":"гардероб","vi":"tủ quần áo","fa":"کمد لباس","examples":[{"de":"Bitte geben Sie Ihren Mantel an der Garderobe ab.","en":"Please leave your coat at the cloakroom.","ru":"Пожалуйста, сдайте пальто в гардероб.","vi":"Vui lòng để áo khoác của bạn ở phòng thay đồ.","fa":"لطفا کت خود را در رختکن بگذارید."},{"de":"Ihre Garderobe zu Hause ist sehr groß.","en":"Her wardrobe at home is very large.","ru":"Её гардероб дома очень большой.","vi":"Tủ quần áo ở nhà của bạn rất lớn.","fa":"کمد لباس شما در خانه بسیار بزرگ است."}]},{"word":"gären","en":"to ferment","ru":"бродить (о брожении)","vi":"lên men","fa":"تخمیر","examples":[{"de":"Der Most muss mehrere Wochen gären, bevor er zu Wein wird.","en":"The must has to ferment for several weeks before it becomes wine.","ru":"Фруктовый сок должен бродить несколько недель, прежде чем станет вином.","vi":"Phải lên men trong vài tuần trước khi trở thành rượu vang.","fa":"باید چند هفته تخمیر شود تا به شراب تبدیل شود."},{"de":"Während das Bier gärt, darf man den Behälter nicht öffnen.","en":"While the beer is fermenting, you must not open the container.","ru":"Пока пиво бродит, ёмкость нельзя открывать.","vi":"Không mở hộp đựng khi bia đang lên men.","fa":"در زمانی که آبجو در حال تخمیر است در ظرف را باز نکنید."},{"de":"Der Saft begann in der Wärme zu gären.","en":"The juice began to ferment in the warmth.","ru":"Сок начал бродить в тепле.","vi":"Nước ép bắt đầu lên men trong hơi ấm.","fa":"آب میوه در گرما شروع به تخمیر کرد."}]},{"word":"der Garten","en":"garden","ru":"сад","vi":"khu vườn","fa":"باغ","examples":[{"de":"Im Sommer arbeiten wir viel im Garten.","en":"In summer we work a lot in the garden.","ru":"Летом мы много работаем в саду.","vi":"Vào mùa hè, chúng tôi làm việc rất nhiều trong vườn.","fa":"در تابستان زیاد در باغ کار می کنیم."},{"de":"Die Kinder spielen im Garten.","en":"The children are playing in the garden.","ru":"Дети играют в саду.","vi":"Bọn trẻ đang chơi trong vườn.","fa":"بچه ها در باغ بازی می کنند."}]},{"word":"das Gas","en":"gas","ru":"газ","vi":"khí đốt","fa":"گاز","examples":[{"de":"Wir heizen die Wohnung mit Gas.","en":"We heat the apartment with gas.","ru":"Мы отапливаем квартиру газом.","vi":"Chúng tôi sưởi ấm căn hộ bằng gas.","fa":"آپارتمان را با گاز گرم می کنیم."},{"de":"Der Herd funktioniert mit Gas.","en":"The stove runs on gas.","ru":"Плита работает на газе.","vi":"Bếp hoạt động bằng gas.","fa":"اجاق گاز با گاز کار می کند."}]},{"word":"der Gast","en":"guest","ru":"гость","vi":"khách","fa":"مهمان","examples":[{"de":"Wir erwarten heute Abend Gäste.","en":"We are expecting guests tonight.","ru":"Сегодня вечером мы ждём гостей.","vi":"Chúng tôi đang mong đợi khách tối nay.","fa":"امشب منتظر مهمان هستیم."},{"de":"Der Gast bestellt ein Glas Wein.","en":"The guest orders a glass of wine.","ru":"Гость заказывает бокал вина.","vi":"Người khách gọi một ly rượu.","fa":"مهمان یک لیوان شراب سفارش می دهد."}]},{"word":"der Gastarbeiter","en":"migrant worker, guest worker","ru":"гастарбайтер, рабочий-мигрант","vi":"công nhân khách","fa":"the guest worker","examples":[{"de":"In den 1960er Jahren kamen viele Gastarbeiter nach Deutschland.","en":"In the 1960s many guest workers came to Germany.","ru":"В 1960-е годы в Германию приехало много гастарбайтеров.","vi":"Vào những năm 1960, nhiều công nhân khách đã đến Đức.","fa":"در دهه 1960 بسیاری از کارگران مهمان به آلمان آمدند."},{"de":"Mein Großvater war als Gastarbeiter in einer Fabrik tätig.","en":"My grandfather worked as a guest worker in a factory.","ru":"Мой дедушка работал гастарбайтером на фабрике.","vi":"Ông tôi làm công nhân khách ở một nhà máy.","fa":"پدربزرگم به عنوان کارگر مهمان در یک کارخانه کار می کرد."},{"de":"Die Gastarbeiter prägten die Kultur des Landes mit.","en":"The migrant workers helped shape the country's culture.","ru":"Гастарбайтеры внесли свой вклад в культуру страны.","vi":"Các công nhân khách đã giúp hình thành nền văn hóa của đất nước.","fa":"کارگران مهمان به شکل گیری فرهنگ کشور کمک کردند."}]},{"word":"die Gastfamilie","en":"a host family (with whom one lodges)","ru":"принимающая семья (у которой живут)","vi":"gia đình chủ nhà","fa":"the host family","examples":[{"de":"Was hältst du von Gastfamilien als Unterkunft?","en":"What do you think of host families as accommodation?","ru":"Что ты думаешь о принимающих семьях как варианте проживания?","vi":"Bạn nghĩ gì về việc lưu trú tại nhà dân?","fa":"نظر شما در مورد اقامتگاه به عنوان اقامتگاه چیست؟"},{"de":"Während des Austauschs wohnte ich bei einer netten Gastfamilie.","en":"During the exchange I lived with a kind host family.","ru":"Во время обмена я жил в доброй принимающей семье.","vi":"Trong thời gian trao đổi tôi sống với một gia đình bản xứ tốt bụng.","fa":"در طول تبادل من با یک خانواده میزبان خوب زندگی کردم."},{"de":"Meine Gastfamilie hat mir viel über die Kultur des Landes gezeigt.","en":"My host family showed me a lot about the country's culture.","ru":"Моя принимающая семья многое показала мне о культуре страны.","vi":"Gia đình bản xứ đã chỉ cho tôi rất nhiều điều về văn hóa của đất nước này.","fa":"خانواده میزبانم چیزهای زیادی در مورد فرهنگ کشور به من نشان دادند."}]},{"word":"das Gastgeberland","en":"host country","ru":"принимающая страна, страна-организатор","vi":"nước chủ nhà","fa":"the host country","examples":[{"de":"Deutschland war das Gastgeberland der Weltmeisterschaft.","en":"Germany was the host country of the World Cup.","ru":"Германия была принимающей страной чемпионата мира.","vi":"Đức là nước chủ nhà của World Cup.","fa":"آلمان میزبان جام جهانی بود."},{"de":"Das Gastgeberland organisiert die gesamte Veranstaltung.","en":"The host country organises the entire event.","ru":"Принимающая страна организует всё мероприятие.","vi":"Nước chủ nhà tổ chức toàn bộ sự kiện.","fa":"کشور میزبان کل رویداد را سازماندهی می کند."},{"de":"Als Gast sollte man die Regeln des Gastgeberlandes respektieren.","en":"As a guest you should respect the rules of the host country.","ru":"Как гость, следует уважать правила принимающей страны.","vi":"Là khách, bạn nên tôn trọng các quy định của nước sở tại.","fa":"به عنوان یک مهمان باید به قوانین کشور میزبان احترام بگذارید."}]},{"word":"das Gasthaus","en":"inn, guesthouse (with food)","ru":"трактир, постоялый двор (с едой)","vi":"quán trọ","fa":"the inn","examples":[{"de":"Wir kehrten in einem gemütlichen Gasthaus ein.","en":"We stopped at a cosy inn.","ru":"Мы зашли в уютный трактир.","vi":"Chúng tôi dừng lại ở một quán trọ ấm cúng.","fa":"در مسافرخانه ای دنج توقف کردیم."},{"de":"Das Gasthaus serviert regionale Spezialitäten.","en":"The inn serves regional specialities.","ru":"В трактире подают местные блюда.","vi":"Nhà trọ phục vụ đặc sản của vùng.","fa":"این مسافرخانه غذاهای منطقه ای را سرو می کند."},{"de":"Im Dorf gibt es nur ein einziges Gasthaus.","en":"There is only one single inn in the village.","ru":"В деревне есть только один-единственный трактир.","vi":"Trong làng chỉ có một quán trọ.","fa":"در روستا فقط یک مسافرخانه وجود دارد."}]},{"word":"die Gaststätte","en":"restaurant, eatery","ru":"ресторан, закусочная, заведение общепита","vi":"nhà hàng","fa":"رستوران","examples":[{"de":"Diese Gaststätte ist für ihre Schnitzel bekannt.","en":"This restaurant is known for its schnitzel.","ru":"Это заведение известно своими шницелями.","vi":"Nhà hàng này nổi tiếng với món schnitzel.","fa":"این رستوران به خاطر شنیسل هایش معروف است."},{"de":"In der Gaststätte am Markt kann man günstig essen.","en":"You can eat cheaply at the restaurant by the market.","ru":"В заведении у рынка можно недорого поесть.","vi":"Bạn có thể ăn rẻ ở nhà hàng ở chợ.","fa":"شما می توانید با قیمت ارزان در رستوران موجود در بازار غذا بخورید."},{"de":"Die Gaststätte ist montags geschlossen.","en":"The restaurant is closed on Mondays.","ru":"Заведение закрыто по понедельникам.","vi":"Nhà hàng đóng cửa vào thứ Hai.","fa":"رستوران روزهای دوشنبه تعطیل است."}]},{"word":"das Gate","en":"gate (airport boarding gate)","ru":"гейт (выход на посадку в аэропорту)","vi":"cánh cổng","fa":"دروازه","examples":[{"de":"Unser Flug geht von Gate B12 ab.","en":"Our flight departs from gate B12.","ru":"Наш рейс отправляется от гейта B12.","vi":"Chuyến bay của chúng tôi khởi hành từ Cổng B12.","fa":"پرواز ما از گیت B12 حرکت می کند."},{"de":"Bitte begeben Sie sich rechtzeitig zum Gate.","en":"Please make your way to the gate in good time.","ru":"Пожалуйста, вовремя пройдите к гейту.","vi":"Vui lòng đến cổng đúng giờ.","fa":"لطفا به موقع به دروازه بروید."},{"de":"Das Gate wurde kurzfristig geändert.","en":"The gate was changed at short notice.","ru":"Гейт изменили в последний момент.","vi":"Cánh cổng đã được thay đổi trong thời gian ngắn.","fa":"در کوتاه مدت دروازه عوض شد."}]},{"word":"das Gebäck","en":"pastry, baked goods","ru":"выпечка","vi":"bánh ngọt","fa":"شیرینی ها","examples":[{"de":"Zum Kaffee gibt es frisches Gebäck.","en":"There's fresh pastry with the coffee.","ru":"К кофе подают свежую выпечку.","vi":"Có bánh ngọt tươi với cà phê.","fa":"شیرینی های تازه با قهوه وجود دارد."},{"de":"Sie hat für das Fest Gebäck gebacken.","en":"She baked pastries for the party.","ru":"Она испекла выпечку к празднику.","vi":"Cô nướng bánh ngọt cho lễ hội.","fa":"او برای جشنواره شیرینی پخت."}]},{"word":"das Gebäude","en":"building","ru":"здание","vi":"tòa nhà","fa":"ساختمان","examples":[{"de":"Das Gebäude ist über hundert Jahre alt.","en":"The building is over a hundred years old.","ru":"Зданию больше ста лет.","vi":"Tòa nhà đã hơn một trăm năm tuổi.","fa":"قدمت این بنا بیش از صد سال است."},{"de":"In diesem Gebäude befindet sich das Büro.","en":"The office is located in this building.","ru":"В этом здании находится офис.","vi":"Văn phòng nằm trong tòa nhà này.","fa":"دفتر در این ساختمان واقع شده است."}]},{"word":"geben","en":"to give","ru":"давать","vi":"cho","fa":"دادن","examples":[{"de":"Kannst du mir bitte das Buch geben?","en":"Can you please give me the book?","ru":"Можешь дать мне книгу, пожалуйста?","vi":"Bạn có thể vui lòng cho tôi cuốn sách được không?","fa":"میشه لطفا کتاب رو به من بدید؟"},{"de":"Es gibt heute keine Schule.","en":"There is no school today.","ru":"Сегодня нет школы.","vi":"Hôm nay không có trường học.","fa":"امروز مدرسه نیست."}]},{"word":"das Gebiet","en":"area, region","ru":"область, район","vi":"khu vực","fa":"منطقه","examples":[{"de":"In diesem Gebiet gibt es viele Wälder.","en":"There are many forests in this area.","ru":"В этой области много лесов.","vi":"Có rất nhiều rừng ở khu vực này.","fa":"جنگل های زیادی در این منطقه وجود دارد."},{"de":"Er ist Experte auf seinem Gebiet.","en":"He is an expert in his field.","ru":"Он эксперт в своей области.","vi":"Anh ấy là một chuyên gia trong lĩnh vực của mình.","fa":"او در رشته خود متخصص است."}]},{"word":"das Gebirge","en":"mountains, mountain range","ru":"горы, горный массив","vi":"những ngọn núi","fa":"کوه ها","examples":[{"de":"Wir fahren im Urlaub ins Gebirge.","en":"We're going to the mountains on vacation.","ru":"В отпуске мы едем в горы.","vi":"Chúng tôi đang đi nghỉ ở vùng núi.","fa":"ما برای تعطیلات به کوه می رویم."},{"de":"Das Gebirge ist im Winter mit Schnee bedeckt.","en":"The mountain range is covered with snow in winter.","ru":"Зимой горы покрыты снегом.","vi":"Những ngọn núi được bao phủ bởi tuyết vào mùa đông.","fa":"کوه ها در زمستان پوشیده از برف هستند."}]},{"word":"geboren werden","en":"to be born","ru":"родиться","vi":"được sinh ra","fa":"متولد شود","examples":[{"de":"Meine Schwester wurde 1995 geboren.","en":"My sister was born in 1995.","ru":"Моя сестра родилась в 1995 году.","vi":"Em gái tôi sinh năm 1995.","fa":"خواهرم متولد 1374 است."},{"de":"Wo bist du geboren?","en":"Where were you born?","ru":"Где ты родился?","vi":"Bạn sinh ra ở đâu?","fa":"کجا متولد شدی؟"}]},{"word":"gebrauchen","en":"to use","ru":"использовать, употреблять","vi":"sử dụng","fa":"استفاده کنید","examples":[{"de":"Ich kann deine Hilfe gut gebrauchen.","en":"I can really use your help.","ru":"Мне очень пригодится твоя помощь.","vi":"Tôi thực sự có thể sử dụng sự giúp đỡ của bạn.","fa":"من واقعا می توانم از کمک شما استفاده کنم."},{"de":"Dieses Werkzeug wird selten gebraucht.","en":"This tool is rarely used.","ru":"Этот инструмент используется редко.","vi":"Công cụ này hiếm khi được sử dụng.","fa":"این ابزار به ندرت استفاده می شود."}]},{"word":"die Gebrauchsanweisung","en":"instructions for use","ru":"инструкция по применению","vi":"hướng dẫn sử dụng","fa":"دستورالعمل استفاده","examples":[{"de":"Lies zuerst die Gebrauchsanweisung, bevor du das Gerät benutzt.","en":"Read the instructions first before using the device.","ru":"Сначала прочитай инструкцию, прежде чем пользоваться прибором.","vi":"Đọc hướng dẫn trước khi sử dụng thiết bị.","fa":"قبل از استفاده از دستگاه ابتدا دستورالعمل ها را بخوانید."},{"de":"Die Gebrauchsanweisung liegt der Packung bei.","en":"The instructions are included with the package.","ru":"Инструкция прилагается к упаковке.","vi":"Hướng dẫn sử dụng được bao gồm trong gói.","fa":"دستورالعمل استفاده در بسته موجود است."}]},{"word":"die Gebühr","en":"fee","ru":"сбор, плата","vi":"lệ phí","fa":"هزینه","examples":[{"de":"Für die Nutzung fällt eine kleine Gebühr an.","en":"A small fee is charged for use.","ru":"За пользование взимается небольшая плата.","vi":"Có một khoản phí nhỏ để sử dụng.","fa":"هزینه کمی برای استفاده وجود دارد."},{"de":"Die Bank erhebt Gebühren für die Kontoführung.","en":"The bank charges fees for account management.","ru":"Банк взимает плату за ведение счёта.","vi":"Ngân hàng tính phí quản lý tài khoản.","fa":"بانک برای مدیریت حساب کارمزد دریافت می کند."}]},{"word":"die Geburt","en":"birth","ru":"рождение","vi":"sự ra đời","fa":"تولد","examples":[{"de":"Die Geburt des Kindes war ein großes Glück.","en":"The birth of the child was a great joy.","ru":"Рождение ребёнка было большим счастьем.","vi":"Sự ra đời của đứa trẻ là một niềm hạnh phúc lớn lao.","fa":"تولد فرزند نعمت بزرگی بود."},{"de":"Nach der Geburt bleibt die Mutter einige Tage im Krankenhaus.","en":"After the birth, the mother stays in the hospital for a few days.","ru":"После родов мать остаётся в больнице несколько дней.","vi":"Sau khi sinh, người mẹ ở lại bệnh viện vài ngày.","fa":"پس از زایمان، مادر چند روز در بیمارستان می ماند."}]},{"word":"der Gedanke","en":"thought, idea","ru":"мысль, идея","vi":"suy nghĩ","fa":"فکر","examples":[{"de":"Mir ist ein guter Gedanke gekommen.","en":"A good idea came to me.","ru":"Мне пришла хорошая мысль.","vi":"Một ý nghĩ tốt chợt đến với tôi.","fa":"فکر خوبی به ذهنم رسید."},{"de":"Seine Gedanken waren ganz woanders.","en":"His thoughts were somewhere else entirely.","ru":"Его мысли были совсем в другом месте.","vi":"Suy nghĩ của anh hoàn toàn ở một nơi khác.","fa":"افکار او کاملاً جای دیگری بود."},{"de":"Der Gedanke an die Prüfung macht mich nervös.","en":"The thought of the exam makes me nervous.","ru":"Мысль об экзамене меня нервирует.","vi":"Ý nghĩ về kỳ thi khiến tôi lo lắng.","fa":"فکر امتحان من را عصبی می کند."}]},{"word":"das Gedicht","en":"poem","ru":"стихотворение","vi":"bài thơ","fa":"شعر","examples":[{"de":"Die Schüler lernen ein Gedicht auswendig.","en":"The students are learning a poem by heart.","ru":"Ученики учат стихотворение наизусть.","vi":"Học sinh ghi nhớ một bài thơ.","fa":"دانش آموزان یک شعر را حفظ می کنند."},{"de":"Er hat seiner Frau ein Gedicht geschrieben.","en":"He wrote a poem for his wife.","ru":"Он написал стихотворение для своей жены.","vi":"Anh viết bài thơ tặng vợ.","fa":"برای همسرش شعری نوشت."}]},{"word":"die Geduld","en":"patience","ru":"терпение","vi":"sự kiên nhẫn","fa":"صبر","examples":[{"de":"Bei diesem Job braucht man viel Geduld.","en":"You need a lot of patience for this job.","ru":"Для этой работы нужно много терпения.","vi":"Công việc này đòi hỏi rất nhiều kiên nhẫn.","fa":"این کار به صبر و حوصله زیادی نیاز دارد."},{"de":"Meine Geduld ist gleich zu Ende.","en":"My patience is about to run out.","ru":"Моё терпение вот-вот закончится.","vi":"Sự kiên nhẫn của tôi sắp cạn kiệt rồi.","fa":"صبرم داره تموم میشه"}]},{"word":"geehrt","en":"honored, esteemed","ru":"уважаемый, почтённый","vi":"vinh dự","fa":"مفتخر شد","examples":[{"de":"Sehr geehrte Damen und Herren, ich schreibe Ihnen wegen meiner Bewerbung.","en":"Dear Sir or Madam, I am writing to you regarding my application.","ru":"Уважаемые дамы и господа, я пишу вам по поводу моей заявки.","vi":"Thưa ông hoặc bà, tôi viết thư này cho bạn về đơn đăng ký của tôi.","fa":"آقا یا خانم عزیز، من در مورد درخواستم برای شما می نویسم."},{"de":"Wir fühlen uns geehrt, Sie bei uns begrüßen zu dürfen.","en":"We feel honored to welcome you here.","ru":"Мы польщены возможностью приветствовать вас у себя.","vi":"Chúng tôi rất vinh dự được chào đón bạn.","fa":"استقبال از شما مفتخریم"}]},{"word":"geeignet","en":"suitable","ru":"подходящий","vi":"phù hợp","fa":"مناسب","examples":[{"de":"Dieser Film ist nicht für Kinder geeignet.","en":"This movie is not suitable for children.","ru":"Этот фильм не подходит для детей.","vi":"Bộ phim này không phù hợp với trẻ em.","fa":"این فیلم برای کودکان مناسب نیست."},{"de":"Sie ist die geeignete Person für diese Aufgabe.","en":"She is the right person for this task.","ru":"Она подходящий человек для этой задачи.","vi":"Cô ấy là người phù hợp cho nhiệm vụ này.","fa":"او فرد مناسبی برای این کار است."}]},{"word":"die Gefahr","en":"danger","ru":"опасность","vi":"sự nguy hiểm","fa":"خطر","examples":[{"de":"Bei Sturm besteht Gefahr im Wald.","en":"There is danger in the forest during a storm.","ru":"Во время шторма в лесу есть опасность.","vi":"Có mối nguy hiểm trong rừng khi có bão.","fa":"در هنگام طوفان خطری در جنگل وجود دارد."},{"de":"Rauchen ist eine Gefahr für die Gesundheit.","en":"Smoking is a danger to health.","ru":"Курение опасно для здоровья.","vi":"Hút thuốc là một mối nguy hiểm cho sức khỏe.","fa":"سیگار کشیدن یک خطر برای سلامتی است."}]},{"word":"gefährlich","en":"dangerous","ru":"опасный","vi":"nguy hiểm","fa":"خطرناک","examples":[{"de":"Das Schwimmen in diesem Fluss ist gefährlich.","en":"Swimming in this river is dangerous.","ru":"Плавать в этой реке опасно.","vi":"Bơi ở con sông này rất nguy hiểm.","fa":"شنا در این رودخانه خطرناک است."},{"de":"Bei Glatteis ist das Autofahren besonders gefährlich.","en":"Driving is especially dangerous in icy conditions.","ru":"В гололёд водить машину особенно опасно.","vi":"Lái xe đặc biệt nguy hiểm khi có băng đen.","fa":"رانندگی به ویژه در صورت وجود یخ سیاه خطرناک است."}]},{"word":"gefallen","en":"to like, to please","ru":"нравиться","vi":"thích","fa":"دوست داشت","examples":[{"de":"Das Kleid gefällt mir sehr gut.","en":"I like the dress very much.","ru":"Это платье мне очень нравится.","vi":"Tôi thích chiếc váy rất nhiều.","fa":"من لباس را خیلی دوست دارم."},{"de":"Wie hat dir der Film gefallen?","en":"How did you like the movie?","ru":"Как тебе понравился фильм?","vi":"Bạn thích bộ phim như thế nào?","fa":"فیلم را چگونه دوست داشتید؟"}]},{"word":"das Gefängnis","en":"prison","ru":"тюрьма","vi":"nhà tù","fa":"زندان","examples":[{"de":"Der Dieb wurde ins Gefängnis gebracht.","en":"The thief was taken to prison.","ru":"Вора отправили в тюрьму.","vi":"Tên trộm bị bắt vào tù.","fa":"دزد را به زندان بردند."},{"de":"Er saß drei Jahre im Gefängnis.","en":"He was in prison for three years.","ru":"Он отсидел три года в тюрьме.","vi":"Anh ta đã ngồi tù ba năm.","fa":"او سه سال در زندان سپری کرد."}]},{"word":"das Gefühl","en":"feeling","ru":"чувство","vi":"cảm giác","fa":"احساس","examples":[{"de":"Ich habe ein komisches Gefühl bei dieser Sache.","en":"I have a strange feeling about this matter.","ru":"У меня странное чувство по поводу этого дела.","vi":"Tôi có một cảm giác kỳ lạ về điều này.","fa":"احساس عجیبی در این مورد دارم."},{"de":"Sie zeigt ihre Gefühle nicht gern.","en":"She doesn't like to show her feelings.","ru":"Она не любит показывать свои чувства.","vi":"Cô ấy không thích thể hiện cảm xúc của mình.","fa":"او دوست ندارد احساسات خود را نشان دهد."}]},{"word":"gegen","en":"against; around (time)","ru":"против; около (о времени)","vi":"chống lại","fa":"علیه","examples":[{"de":"Die Mannschaft spielt heute gegen den Tabellenführer.","en":"The team is playing against the league leader today.","ru":"Сегодня команда играет против лидера таблицы.","vi":"Hôm nay đội thi đấu với đội dẫn đầu giải đấu.","fa":"این تیم امروز به مصاف رهبران لیگ می رود."},{"de":"Ich komme gegen acht Uhr nach Hause.","en":"I'll come home around eight o'clock.","ru":"Я приду домой около восьми часов.","vi":"Tôi về nhà vào khoảng tám giờ.","fa":"حوالی ساعت هشت به خانه می رسم."}]},{"word":"die Gegend","en":"area, region","ru":"местность, район","vi":"khu vực","fa":"منطقه","examples":[{"de":"Wir wohnen in einer ruhigen Gegend.","en":"We live in a quiet area.","ru":"Мы живём в тихом районе.","vi":"Chúng tôi sống trong một khu vực yên tĩnh.","fa":"ما در یک منطقه آرام زندگی می کنیم."},{"de":"Kennst du eine gute Gegend zum Wandern?","en":"Do you know a good area for hiking?","ru":"Ты знаешь хорошее место для походов?","vi":"Bạn có biết khu vực nào tốt để đi bộ đường dài không?","fa":"آیا منطقه خوبی برای پیاده روی می شناسید؟"}]},{"word":"der Gegensatz","en":"contrast, opposite","ru":"противоположность, контраст","vi":"điều ngược lại","fa":"برعکس","examples":[{"de":"Im Gegensatz zu ihrem Bruder ist sie sehr ruhig.","en":"In contrast to her brother, she is very calm.","ru":"В отличие от своего брата, она очень спокойная.","vi":"Không giống như anh trai mình, cô ấy rất bình tĩnh.","fa":"او برخلاف برادرش بسیار آرام است."},{"de":"Die beiden Meinungen stehen im Gegensatz zueinander.","en":"The two opinions are in contrast to each other.","ru":"Оба мнения противоречат друг другу.","vi":"Hai ý kiến ​​trái ngược nhau.","fa":"این دو نظر با یکدیگر متناقض هستند."}]},{"word":"gegenseitig","en":"mutual; each other","ru":"взаимный; друг друга","vi":"lẫn nhau","fa":"یکدیگر","examples":[{"de":"Sie helfen sich gegenseitig bei den Hausaufgaben.","en":"They help each other with their homework.","ru":"Они помогают друг другу с домашней работой.","vi":"Họ giúp đỡ nhau làm bài tập về nhà.","fa":"آنها در انجام تکالیف به یکدیگر کمک می کنند."},{"de":"Eine gute Beziehung beruht auf gegenseitigem Respekt.","en":"A good relationship is based on mutual respect.","ru":"Хорошие отношения основаны на взаимном уважении.","vi":"Một mối quan hệ tốt dựa trên sự tôn trọng lẫn nhau.","fa":"یک رابطه خوب مبتنی بر احترام متقابل است."}]},{"word":"der Gegenstand","en":"object","ru":"предмет","vi":"đối tượng","fa":"شی","examples":[{"de":"Auf dem Tisch liegen mehrere Gegenstände.","en":"There are several objects on the table.","ru":"На столе лежат несколько предметов.","vi":"Có một số đồ vật trên bàn.","fa":"چندین شی روی میز وجود دارد."},{"de":"Das Thema war Gegenstand einer langen Diskussion.","en":"The topic was the subject of a long discussion.","ru":"Тема была предметом долгого обсуждения.","vi":"Chủ đề này là chủ đề của một cuộc thảo luận dài.","fa":"موضوع موضوع بحث طولانی بود."}]},{"word":"das Gegenteil","en":"opposite","ru":"противоположность","vi":"điều ngược lại","fa":"برعکس","examples":[{"de":"Das Gegenteil von \"groß\" ist \"klein\".","en":"The opposite of \"big\" is \"small\".","ru":"Противоположность слова «большой» — «маленький».","vi":"Ngược lại với \"lớn\" là \"nhỏ\".","fa":"نقطه مقابل \"بزرگ\" \"کوچک\" است."},{"de":"Sie tut immer das Gegenteil von dem, was man ihr sagt.","en":"She always does the opposite of what she's told.","ru":"Она всегда делает противоположное тому, что ей говорят.","vi":"Cô ấy luôn làm ngược lại những gì được bảo.","fa":"او همیشه برخلاف آنچه به او گفته می شود عمل می کند."}]},{"word":"gegenüber","en":"opposite; towards","ru":"напротив; по отношению к","vi":"ngược lại","fa":"مقابل","examples":[{"de":"Die Bäckerei liegt gegenüber der Kirche.","en":"The bakery is located opposite the church.","ru":"Пекарня находится напротив церкви.","vi":"Tiệm bánh nằm đối diện nhà thờ.","fa":"نانوایی روبروی کلیسا است."},{"de":"Er ist seinen Kollegen gegenüber immer freundlich.","en":"He is always friendly towards his colleagues.","ru":"Он всегда дружелюбен по отношению к коллегам.","vi":"Anh ấy luôn thân thiện với đồng nghiệp.","fa":"او همیشه با همکارانش دوستانه رفتار می کند."}]},{"word":"der Gegner","en":"opponent, adversary","ru":"противник, соперник","vi":"đối thủ","fa":"the opponent","examples":[{"de":"Unsere Mannschaft hat den Gegner besiegt.","en":"Our team beat the opponent.","ru":"Наша команда победила соперника.","vi":"Đội của chúng tôi đã đánh bại đối thủ.","fa":"تیم ما حریف را شکست داد."},{"de":"Er ist ein entschiedener Gegner dieser Reform.","en":"He is a determined opponent of this reform.","ru":"Он — решительный противник этой реформы.","vi":"Ông là một người phản đối kịch liệt cuộc cải cách này.","fa":"او از مخالفان سرسخت این اصلاحات است."},{"de":"Der Gegner war stärker als erwartet.","en":"The opponent was stronger than expected.","ru":"Соперник оказался сильнее, чем ожидалось.","vi":"Đối thủ mạnh hơn dự kiến.","fa":"حریف قوی تر از حد انتظار بود."}]},{"word":"das Gehalt","en":"salary","ru":"зарплата","vi":"tiền lương","fa":"حقوق و دستمزد","examples":[{"de":"Sie bekommt jeden Monat ein festes Gehalt.","en":"She receives a fixed salary every month.","ru":"Она каждый месяц получает фиксированную зарплату.","vi":"Cô nhận được một mức lương cố định hàng tháng.","fa":"او هر ماه حقوق ثابتی دریافت می کند."},{"de":"Das Gehalt wurde dieses Jahr erhöht.","en":"The salary was increased this year.","ru":"В этом году зарплату повысили.","vi":"Năm nay lương đã tăng.","fa":"حقوق امسال افزایش یافت."}]},{"word":"geheim","en":"secret","ru":"тайный, секретный","vi":"bí mật","fa":"راز","examples":[{"de":"Das ist ein geheimes Rezept meiner Großmutter.","en":"This is a secret recipe from my grandmother.","ru":"Это секретный рецепт от моей бабушки.","vi":"Đây là một công thức bí mật từ bà tôi.","fa":"این یک دستور غذای مخفی از مادربزرگ من است."},{"de":"Die Unterlagen sind streng geheim.","en":"The documents are top secret.","ru":"Документы совершенно секретны.","vi":"Các tài liệu là tuyệt mật.","fa":"اسناد فوق محرمانه هستند."},{"de":"Sie trafen sich an einem geheimen Ort.","en":"They met at a secret place.","ru":"Они встретились в тайном месте.","vi":"Họ gặp nhau ở một nơi bí mật.","fa":"آنها در یک مکان مخفی ملاقات کردند."}]},{"word":"das Geheimnis","en":"secret","ru":"тайна, секрет","vi":"bí mật","fa":"راز","examples":[{"de":"Kannst du ein Geheimnis für dich behalten?","en":"Can you keep a secret?","ru":"Ты умеешь хранить тайну?","vi":"Bạn có thể giữ bí mật được không?","fa":"آیا می توانید یک راز را حفظ کنید؟"},{"de":"Sie hat mir ihr Geheimnis anvertraut.","en":"She confided her secret to me.","ru":"Она доверила мне свою тайну.","vi":"Cô ấy kể cho tôi nghe bí mật của cô ấy.","fa":"رازش را به من گفت."}]},{"word":"gehen","en":"to go, to walk","ru":"идти","vi":"đi","fa":"برو","examples":[{"de":"Ich gehe jeden Tag zu Fuß zur Arbeit.","en":"I walk to work every day.","ru":"Я каждый день хожу на работу пешком.","vi":"Tôi đi bộ đi làm mỗi ngày.","fa":"هر روز پیاده روی سر کار می روم."},{"de":"Wie geht es dir?","en":"How are you?","ru":"Как у тебя дела?","vi":"Bạn dạo này thế nào?","fa":"حال شما چطور است؟"}]},{"word":"gehören","en":"to belong","ru":"принадлежать","vi":"thuộc về","fa":"متعلق به","examples":[{"de":"Dieses Auto gehört meinem Vater.","en":"This car belongs to my father.","ru":"Эта машина принадлежит моему отцу.","vi":"Chiếc xe này thuộc về bố tôi.","fa":"این ماشین مال پدرم است."},{"de":"Zu einem guten Frühstück gehört frisches Brot.","en":"Fresh bread is part of a good breakfast.","ru":"К хорошему завтраку относится свежий хлеб.","vi":"Bữa sáng ngon miệng bao gồm bánh mì tươi.","fa":"یک صبحانه خوب شامل نان تازه است."}]},{"word":"gehörlos","en":"deaf","ru":"глухой (лишённый слуха)","vi":"điếc","fa":"ناشنوا","examples":[{"de":"Mein Nachbar ist seit seiner Geburt gehörlos.","en":"My neighbour has been deaf since birth.","ru":"Мой сосед глухой от рождения.","vi":"Hàng xóm của tôi bị điếc từ khi sinh ra.","fa":"همسایه من از بدو تولد ناشنوا بوده است."},{"de":"Gehörlose Menschen kommunizieren oft in Gebärdensprache.","en":"Deaf people often communicate in sign language.","ru":"Глухие люди часто общаются на языке жестов.","vi":"Người điếc thường giao tiếp bằng ngôn ngữ ký hiệu.","fa":"افراد ناشنوا اغلب به زبان اشاره ارتباط برقرار می کنند."},{"de":"Es gibt spezielle Schulen für gehörlose Kinder.","en":"There are special schools for deaf children.","ru":"Есть специальные школы для глухих детей.","vi":"Có trường học đặc biệt dành cho trẻ điếc.","fa":"مدارس ویژه ای برای کودکان ناشنوا وجود دارد."}]},{"word":"der Gehsteig","en":"sidewalk, pavement","ru":"тротуар","vi":"vỉa hè","fa":"پیاده رو","examples":[{"de":"Fahrräder dürfen nicht auf dem Gehsteig fahren.","en":"Bicycles are not allowed to ride on the sidewalk.","ru":"Велосипедам нельзя ездить по тротуару.","vi":"Xe đạp không được phép đi trên vỉa hè.","fa":"دوچرخه سواری در پیاده رو ممنوع است."},{"de":"Die Kinder spielen auf dem Gehsteig vor dem Haus.","en":"The children are playing on the sidewalk in front of the house.","ru":"Дети играют на тротуаре перед домом.","vi":"Lũ trẻ đang chơi đùa trên vỉa hè trước nhà.","fa":"بچه ها در پیاده رو جلوی خانه بازی می کنند."}]},{"word":"der Gehweg","en":"pavement, footpath","ru":"тротуар, пешеходная дорожка","vi":"vỉa hè","fa":"پیاده رو","examples":[{"de":"Fußgänger sollen den Gehweg benutzen.","en":"Pedestrians should use the footpath.","ru":"Пешеходы должны пользоваться пешеходной дорожкой.","vi":"Người đi bộ nên sử dụng vỉa hè.","fa":"عابران پیاده باید از پیاده رو استفاده کنند."},{"de":"Der Gehweg ist durch Bauarbeiten gesperrt.","en":"The footpath is closed due to construction work.","ru":"Тротуар закрыт из-за строительных работ.","vi":"Vỉa hè bị đóng do công trình xây dựng.","fa":"پیاده رو به دلیل کار ساختمانی بسته است."},{"de":"Sie schob den Kinderwagen über den Gehweg.","en":"She pushed the pram along the pavement.","ru":"Она катила коляску по тротуару.","vi":"Cô đẩy xe đẩy dọc theo vỉa hè.","fa":"کالسکه را کنار پیاده رو هل داد."}]},{"word":"geizig","en":"stingy; mean","ru":"скупой; жадный","vi":"keo kiệt","fa":"خسیس","examples":[{"de":"Er ist so geizig, dass er nie ein Trinkgeld gibt.","en":"He is so stingy that he never leaves a tip.","ru":"Он такой жадный, что никогда не оставляет чаевых.","vi":"Anh ta keo kiệt đến mức không bao giờ để lại tiền boa.","fa":"او آنقدر خسیس است که هرگز انعام نمی گذارد."},{"de":"Sei nicht so geizig und lade uns ein!","en":"Don't be so stingy and treat us!","ru":"Не будь таким жадным и угости нас!","vi":"Đừng keo kiệt thế mà hãy mời chúng tôi đi!","fa":"اینقدر خسیس نباش و ما را دعوت کن!"}]},{"word":"die Gelassenheit","en":"composure, serenity","ru":"невозмутимость, спокойствие, безмятежность","vi":"sự thanh thản","fa":"آرامش","examples":[{"de":"Mit der Zeit bringt Yoga mehr Gelassenheit in mein Leben.","en":"Over time, yoga brings more serenity into my life.","ru":"Со временем йога привносит больше спокойствия в мою жизнь.","vi":"Theo thời gian, yoga mang lại sự thanh thản hơn cho cuộc sống của tôi.","fa":"با گذشت زمان، یوگا آرامش بیشتری را به زندگی من می آورد."},{"de":"Sie reagierte mit erstaunlicher Gelassenheit auf den Stress.","en":"She reacted to the stress with astonishing composure.","ru":"Она отреагировала на стресс с удивительным спокойствием.","vi":"Cô ấy phản ứng lại sự căng thẳng bằng sự bình tĩnh đáng kinh ngạc.","fa":"او با آرامش شگفت انگیزی به استرس پاسخ داد."},{"de":"Gelassenheit lässt sich üben wie ein Muskel.","en":"Composure can be trained like a muscle.","ru":"Невозмутимость можно тренировать, как мышцу.","vi":"Sự bình tĩnh có thể được luyện tập giống như cơ bắp.","fa":"آرامش را می توان مانند یک ماهیچه تمرین کرد."}]},{"word":"das Geld","en":"money","ru":"деньги","vi":"tiền","fa":"پول","examples":[{"de":"Ich habe nicht genug Geld dabei.","en":"I don't have enough money with me.","ru":"У меня с собой недостаточно денег.","vi":"Tôi không có đủ tiền bên mình.","fa":"من پول کافی با خودم ندارم."},{"de":"Er spart Geld für ein neues Auto.","en":"He is saving money for a new car.","ru":"Он копит деньги на новую машину.","vi":"Anh ấy đang tiết kiệm tiền để mua một chiếc ô tô mới.","fa":"او برای یک ماشین جدید پول پس انداز می کند."}]},{"word":"Geld überweisen","en":"to transfer money","ru":"переводить деньги (перечислять)","vi":"chuyển tiền","fa":"انتقال پول","examples":[{"de":"Ich muss heute noch die Miete überweisen.","en":"I still have to transfer the rent today.","ru":"Мне сегодня ещё нужно перевести деньги за аренду.","vi":"Hôm nay tôi vẫn phải trả tiền thuê nhà.","fa":"من هنوز باید اجاره خانه را امروز پرداخت کنم."},{"de":"Kannst du mir das Geld auf mein Konto überweisen?","en":"Can you transfer the money to my account?","ru":"Можешь перевести мне деньги на счёт?","vi":"Bạn có thể chuyển tiền vào tài khoản của tôi được không?","fa":"آیا می توانید پول را به حساب من واریز کنید؟"},{"de":"Die Firma überweist den Lohn am Monatsende.","en":"The company transfers the wages at the end of the month.","ru":"Фирма перечисляет зарплату в конце месяца.","vi":"Công ty chuyển lương vào cuối tháng.","fa":"این شرکت دستمزد را در پایان ماه منتقل می کند."}]},{"word":"der Geldautomat","en":"ATM, cash machine","ru":"банкомат","vi":"máy ATM","fa":"دستگاه خودپرداز","examples":[{"de":"Ich hebe Geld am Geldautomaten ab.","en":"I'm withdrawing money from the ATM.","ru":"Я снимаю деньги в банкомате.","vi":"Tôi rút tiền từ máy ATM.","fa":"من از خودپرداز پول برداشت می کنم."},{"de":"Der Geldautomat vor der Bank ist gerade außer Betrieb.","en":"The ATM in front of the bank is currently out of order.","ru":"Банкомат перед банком сейчас не работает.","vi":"Máy ATM trước ngân hàng hiện không hoạt động.","fa":"دستگاه خودپرداز جلوی بانک در حال حاضر از کار افتاده است."}]},{"word":"der Geldbeutel","en":"wallet, purse","ru":"кошелёк","vi":"cái ví","fa":"کیف پول","examples":[{"de":"Mein Geldbeutel ist am Ende des Monats leer.","en":"My wallet is empty at the end of the month.","ru":"К концу месяца мой кошелёк пуст.","vi":"Ví của tôi trống rỗng vào cuối tháng.","fa":"کیف پول من در پایان ماه خالی است."},{"de":"Sie hat ihren Geldbeutel im Bus verloren.","en":"She lost her wallet on the bus.","ru":"Она потеряла свой кошелёк в автобусе.","vi":"Cô ấy bị mất ví trên xe buýt.","fa":"کیف پولش را در اتوبوس گم کرد."},{"de":"Das schont den Geldbeutel der Familie.","en":"That is easy on the family's purse.","ru":"Это щадит семейный кошелёк.","vi":"Điều này tiết kiệm ví tiền của gia đình.","fa":"این باعث صرفه جویی در کیف پول خانواده می شود."}]},{"word":"die Geldbörse","en":"wallet, purse","ru":"кошелёк","vi":"cái ví","fa":"کیف پول","examples":[{"de":"Ich habe meine Geldbörse im Bus vergessen.","en":"I forgot my wallet on the bus.","ru":"Я забыл кошелёк в автобусе.","vi":"Tôi quên ví trên xe buýt.","fa":"کیف پولم را در اتوبوس فراموش کردم."},{"de":"In ihrer Geldbörse sind Karten und ein wenig Bargeld.","en":"There are cards and a little cash in her wallet.","ru":"В её кошельке карты и немного наличных.","vi":"Có thẻ và một ít tiền mặt trong ví của cô ấy.","fa":"در کیف پولش کارت و مقداری پول نقد هست."}]},{"word":"die Gelegenheit","en":"opportunity","ru":"возможность, случай","vi":"cơ hội","fa":"فرصت","examples":[{"de":"Das ist eine gute Gelegenheit, Deutsch zu üben.","en":"This is a good opportunity to practice German.","ru":"Это хорошая возможность попрактиковать немецкий.","vi":"Đây là cơ hội tốt để thực hành tiếng Đức.","fa":"این فرصت خوبی برای تمرین زبان آلمانی است."},{"de":"Ich hatte noch keine Gelegenheit, ihn anzurufen.","en":"I haven't had the chance to call him yet.","ru":"У меня ещё не было возможности позвонить ему.","vi":"Tôi vẫn chưa có cơ hội gọi cho anh ấy.","fa":"من هنوز فرصت نکردم با او تماس بگیرم."}]},{"word":"das Gelenk","en":"joint","ru":"сустав","vi":"khớp","fa":"مفصل","examples":[{"de":"Bewege jedes Gelenk vorsichtig, bevor du beginnst.","en":"Move each joint carefully before you begin.","ru":"Осторожно разомни каждый сустав, прежде чем начать.","vi":"Nhẹ nhàng di chuyển từng khớp trước khi bạn bắt đầu.","fa":"قبل از شروع هر مفصل را به آرامی حرکت دهید."},{"de":"Yoga hält die Gelenke geschmeidig.","en":"Yoga keeps the joints supple.","ru":"Йога сохраняет суставы гибкими.","vi":"Yoga giúp khớp dẻo dai.","fa":"یوگا مفاصل را انعطاف پذیر نگه می دارد."},{"de":"Bei dieser Haltung darf das Gelenk im Knie nicht schmerzen.","en":"In this posture the knee joint must not hurt.","ru":"В этой позе коленный сустав не должен болеть.","vi":"Ở tư thế này, khớp gối sẽ không bị đau.","fa":"در این حالت، مفصل زانو نباید آسیب ببیند."}]},{"word":"gelingen","en":"to succeed","ru":"удаваться","vi":"thành công","fa":"موفق شدن","examples":[{"de":"Der Kuchen ist mir dieses Mal gut gelungen.","en":"The cake turned out well for me this time.","ru":"На этот раз торт у меня хорошо получился.","vi":"Lần này chiếc bánh trở nên ngon đối với tôi.","fa":"این بار کیک برای من خوب شد."},{"de":"Es gelang ihr, die Prüfung zu bestehen.","en":"She succeeded in passing the exam.","ru":"Ей удалось сдать экзамен.","vi":"Cô đã vượt qua được kỳ thi.","fa":"او موفق به قبولی در امتحان شد."}]},{"word":"gelten","en":"to be valid, to apply","ru":"действовать, считаться","vi":"áp dụng","fa":"اعمال شود","examples":[{"de":"Das Ticket gilt nur an diesem Tag.","en":"The ticket is only valid on this day.","ru":"Билет действителен только в этот день.","vi":"Vé chỉ có giá trị trong ngày này.","fa":"بلیط فقط برای این روز معتبر است."},{"de":"Diese Regel gilt für alle Mitarbeiter.","en":"This rule applies to all employees.","ru":"Это правило распространяется на всех сотрудников.","vi":"Quy tắc này áp dụng cho tất cả nhân viên.","fa":"این قانون برای همه کارکنان اعمال می شود."}]},{"word":"gemeinsam","en":"together, joint","ru":"совместный, вместе","vi":"cùng với nhau","fa":"با هم","examples":[{"de":"Wir haben das Projekt gemeinsam geplant.","en":"We planned the project together.","ru":"Мы вместе спланировали проект.","vi":"Chúng tôi đã cùng nhau lên kế hoạch cho dự án.","fa":"پروژه را با هم برنامه ریزی کردیم."},{"de":"Die Geschwister haben viele gemeinsame Interessen.","en":"The siblings have many common interests.","ru":"У братьев с сёстрами много общих интересов.","vi":"Hai anh em có nhiều sở thích chung.","fa":"خواهر و برادر علایق مشترک زیادی دارند."}]},{"word":"die Gemeinschaft","en":"community","ru":"сообщество, общность","vi":"cộng đồng","fa":"جامعه","examples":[{"de":"Die Dorfbewohner bilden eine enge Gemeinschaft.","en":"The villagers form a close community.","ru":"Жители деревни образуют тесную общину.","vi":"Dân làng tạo thành một cộng đồng gắn bó.","fa":"روستاییان جامعه ای نزدیک به هم تشکیل می دهند."},{"de":"Die Europäische Gemeinschaft besteht aus vielen Ländern.","en":"The European Community consists of many countries.","ru":"Европейское сообщество состоит из многих стран.","vi":"Cộng đồng Châu Âu bao gồm nhiều quốc gia.","fa":"جامعه اروپا متشکل از کشورهای زیادی است."}]},{"word":"das Gemüse","en":"vegetables","ru":"овощи","vi":"các loại rau","fa":"سبزیجات","examples":[{"de":"Sie kauft jede Woche frisches Gemüse auf dem Markt.","en":"She buys fresh vegetables at the market every week.","ru":"Она каждую неделю покупает свежие овощи на рынке.","vi":"Cô ấy mua rau tươi ở chợ mỗi tuần.","fa":"او هر هفته سبزیجات تازه را از بازار می خرد."},{"de":"Man sollte täglich Obst und Gemüse essen.","en":"One should eat fruit and vegetables every day.","ru":"Нужно каждый день есть фрукты и овощи.","vi":"Bạn nên ăn trái cây và rau quả mỗi ngày.","fa":"شما باید هر روز میوه و سبزیجات بخورید."}]},{"word":"gemütlich","en":"cozy","ru":"уютный","vi":"ấm áp","fa":"دنج","examples":[{"de":"Das kleine Café hat eine sehr gemütliche Atmosphäre.","en":"The small café has a very cozy atmosphere.","ru":"В маленьком кафе очень уютная атмосфера.","vi":"Quán cà phê nhỏ có bầu không khí rất ấm cúng.","fa":"کافه کوچک فضایی بسیار دنج دارد."},{"de":"Wir haben einen gemütlichen Abend zu Hause verbracht.","en":"We spent a cozy evening at home.","ru":"Мы провели уютный вечер дома.","vi":"Chúng tôi đã có một buổi tối ấm cúng ở nhà.","fa":"یک شب دنج را در خانه گذراندیم."}]},{"word":"genau","en":"exact, exactly","ru":"точный, точно","vi":"chính xác","fa":"دقیقا","examples":[{"de":"Kannst du mir die genaue Uhrzeit sagen?","en":"Can you tell me the exact time?","ru":"Можешь сказать мне точное время?","vi":"Bạn có thể cho tôi biết thời gian chính xác được không?","fa":"میشه زمان دقیقش رو بگید"},{"de":"Ich weiß nicht genau, wo er wohnt.","en":"I don't know exactly where he lives.","ru":"Я точно не знаю, где он живёт.","vi":"Tôi không biết chính xác nơi anh ấy sống.","fa":"دقیقا نمی دانم کجا زندگی می کند."}]},{"word":"Genau, das stimmt","en":"Exactly, that's right (strong agreement)","ru":"Именно, это верно (полное согласие)","vi":"Chính xác, đúng vậy","fa":"دقیقا همینطوره","examples":[{"de":"Genau, das stimmt — so machen wir es.","en":"Exactly, that's right — let's do it that way.","ru":"Именно, это верно — так и сделаем.","vi":"Chính xác, đúng vậy - đó là cách chúng tôi làm điều đó.","fa":"دقیقاً، درست است - ما این کار را انجام می دهیم."}]},{"word":"genauso","en":"just as, likewise","ru":"точно так же","vi":"giống hệt nhau","fa":"دقیقا همینطور","examples":[{"de":"Sie ist genauso groß wie ihre Mutter.","en":"She is just as tall as her mother.","ru":"Она такого же роста, как её мать.","vi":"Cô ấy có chiều cao tương đương với mẹ cô ấy.","fa":"او هم قد مادرش است."},{"de":"Ich finde den Film genauso langweilig wie du.","en":"I find the movie just as boring as you do.","ru":"Я нахожу этот фильм таким же скучным, как и ты.","vi":"Tôi thấy bộ phim cũng nhàm chán như bạn vậy.","fa":"به نظر من فیلم هم مثل شما خسته کننده است."}]},{"word":"genehmigen","en":"to approve","ru":"разрешать, одобрять","vi":"chấp thuận","fa":"تایید کند","examples":[{"de":"Der Antrag wurde von der Behörde genehmigt.","en":"The application was approved by the authority.","ru":"Заявление было одобрено ведомством.","vi":"Đơn đã được cơ quan có thẩm quyền phê duyệt.","fa":"این درخواست توسط مرجع تایید شد."},{"de":"Mein Chef hat mir zwei Tage Urlaub genehmigt.","en":"My boss approved two days of vacation for me.","ru":"Мой начальник разрешил мне два дня отпуска.","vi":"Ông chủ của tôi đã cho tôi hai ngày nghỉ phép.","fa":"رئیسم به من دو روز مرخصی داد."}]},{"word":"die Genehmigung","en":"permit; approval","ru":"разрешение","vi":"sự chấp thuận","fa":"تایید","examples":[{"de":"Für den Umbau braucht man eine Genehmigung.","en":"You need a permit for the renovation.","ru":"Для перестройки нужно разрешение.","vi":"Bạn cần có giấy phép để chuyển đổi.","fa":"برای تبدیل نیاز به مجوز دارید."},{"de":"Die Genehmigung wurde nach zwei Wochen erteilt.","en":"The approval was granted after two weeks.","ru":"Разрешение выдали через две недели.","vi":"Sự chấp thuận đã được cấp sau hai tuần.","fa":"تایید پس از دو هفته صادر شد."}]},{"word":"die Generation","en":"generation","ru":"поколение","vi":"thế hệ","fa":"نسل","examples":[{"de":"Diese Wohnung gehört seit drei Generationen unserer Familie.","en":"This apartment has belonged to our family for three generations.","ru":"Эта квартира принадлежит нашей семье уже три поколения.","vi":"Căn hộ này đã thuộc về gia đình chúng tôi đã ba thế hệ.","fa":"این آپارتمان سه نسل است که متعلق به خانواده ماست."},{"de":"Die junge Generation nutzt viel mehr digitale Medien.","en":"The younger generation uses much more digital media.","ru":"Молодое поколение гораздо больше пользуется цифровыми медиа.","vi":"Thế hệ trẻ sử dụng phương tiện kỹ thuật số nhiều hơn.","fa":"نسل جوان بیشتر از رسانه های دیجیتال استفاده می کند."}]},{"word":"genervt","en":"annoyed","ru":"раздражённый, нервничающий","vi":"khó chịu","fa":"اذیت شده","examples":[{"de":"Ein Genervter verließ wütend den Raum.","en":"An annoyed man left the room angrily.","ru":"Раздражённый мужчина сердито вышел из комнаты.","vi":"Một người đàn ông khó chịu rời khỏi phòng một cách giận dữ.","fa":"مردی عصبانی با عصبانیت اتاق را ترک کرد."},{"de":"Sie war ziemlich genervt von dem lauten Lärm.","en":"She was rather annoyed by the loud noise.","ru":"Её порядком раздражал громкий шум.","vi":"Cô ấy khá khó chịu vì tiếng ồn lớn.","fa":"او از صدای بلند بسیار اذیت شده بود."},{"de":"Mein Bruder ist genervt, wenn ich seine Sachen nehme.","en":"My brother is annoyed when I take his things.","ru":"Мой брат злится, когда я беру его вещи.","vi":"Anh trai tôi khó chịu khi tôi lấy đồ của anh ấy.","fa":"برادرم وقتی وسایلش را می گیرم اذیت می شود."}]},{"word":"genießen","en":"to enjoy","ru":"наслаждаться","vi":"thưởng thức","fa":"لذت ببرید","examples":[{"de":"Wir genießen den sonnigen Nachmittag im Park.","en":"We are enjoying the sunny afternoon in the park.","ru":"Мы наслаждаемся солнечным днём в парке.","vi":"Chúng tôi tận hưởng buổi chiều đầy nắng trong công viên.","fa":"ما از بعد از ظهر آفتابی در پارک لذت می بریم."},{"de":"Er genießt seinen wohlverdienten Urlaub.","en":"He is enjoying his well-deserved vacation.","ru":"Он наслаждается своим заслуженным отпуском.","vi":"Anh ấy đang tận hưởng kỳ nghỉ xứng đáng của mình.","fa":"او در حال لذت بردن از تعطیلات شایسته خود است."}]},{"word":"genug","en":"enough","ru":"достаточно","vi":"đủ rồi","fa":"به اندازه کافی","examples":[{"de":"Wir haben genug Essen für alle Gäste.","en":"We have enough food for all the guests.","ru":"У нас достаточно еды для всех гостей.","vi":"Chúng tôi có đủ thức ăn cho tất cả khách.","fa":"ما غذای کافی برای همه مهمانان داریم."},{"de":"Ich habe genug von diesem Lärm.","en":"I've had enough of this noise.","ru":"Мне надоел этот шум.","vi":"Tôi đã chịu đủ tiếng ồn này rồi.","fa":"من از این سروصدا به اندازه کافی خسته شدم."}]},{"word":"genügen","en":"to be enough, to suffice","ru":"быть достаточным, хватать","vi":"đủ","fa":"کافی است","examples":[{"de":"Ein kurzer Anruf genügt, um Bescheid zu geben.","en":"A short call is enough to let us know.","ru":"Короткого звонка достаточно, чтобы сообщить.","vi":"Một cuộc gọi nhanh là đủ để cho bạn biết.","fa":"یک تماس سریع برای اطلاع شما کافی است."},{"de":"Zwei Löffel Zucker genügen für den Kuchen.","en":"Two spoons of sugar are enough for the cake.","ru":"Двух ложек сахара достаточно для торта.","vi":"Hai thìa đường là đủ cho chiếc bánh.","fa":"دو قاشق شکر برای کیک کافی است."}]},{"word":"das Genussmittel","en":"luxury food item (coffee, tea, alcohol)","ru":"продукты для удовольствия (кофе, чай, алкоголь, табак)","vi":"món ăn xa xỉ","fa":"غذای لوکس","examples":[{"de":"Kaffee und Tee zählen zu den Genussmitteln.","en":"Coffee and tea are counted among luxury food items.","ru":"Кофе и чай относятся к продуктам для удовольствия.","vi":"Cà phê và trà là những thực phẩm xa xỉ.","fa":"قهوه و چای از غذاهای لوکس هستند."},{"de":"Genussmittel sollte man in Maßen konsumieren.","en":"Luxury food items should be consumed in moderation.","ru":"Такие продукты стоит потреблять в меру.","vi":"Bạn nên tiêu thụ những thực phẩm xa xỉ ở mức độ vừa phải.","fa":"باید غذاهای لوکس را در حد اعتدال مصرف کنید."},{"de":"Alkohol ist ein Genussmittel, kein Grundnahrungsmittel.","en":"Alcohol is a luxury item, not a staple food.","ru":"Алкоголь — это продукт для удовольствия, а не основной продукт питания.","vi":"Rượu là một loại thực phẩm xa xỉ, không phải là thực phẩm thiết yếu.","fa":"الکل یک غذای لوکس است، نه یک غذای اصلی."}]},{"word":"die Geometrie","en":"geometry","ru":"геометрия","vi":"hình học","fa":"هندسه","examples":[{"de":"In der Geometrie geht es um Linien, Winkel und Flächen.","en":"Geometry deals with lines, angles and surfaces.","ru":"В геометрии речь идёт о линиях, углах и плоскостях.","vi":"Hình học là về đường thẳng, góc và bề mặt.","fa":"هندسه درباره خطوط، زوایا و سطوح است."},{"de":"In der Geometrie berechnen wir heute die Fläche eines Dreiecks.","en":"In geometry today we are calculating the area of a triangle.","ru":"На геометрии сегодня мы вычисляем площадь треугольника.","vi":"Trong hình học ngày nay chúng ta tính diện tích của một hình tam giác.","fa":"در هندسه امروز مساحت یک مثلث را محاسبه می کنیم."},{"de":"Die Architektin nutzt die Geometrie, um stabile Gebäude zu entwerfen.","en":"The architect uses geometry to design stable buildings.","ru":"Архитектор использует геометрию, чтобы проектировать устойчивые здания.","vi":"Kiến trúc sư sử dụng hình học để thiết kế các tòa nhà ổn định.","fa":"معمار از هندسه برای طراحی ساختمان های پایدار استفاده می کند."}]},{"word":"das Gepäck","en":"luggage","ru":"багаж","vi":"hành lý","fa":"چمدان","examples":[{"de":"Bitte stellen Sie Ihr Gepäck hier ab.","en":"Please put your luggage down here.","ru":"Пожалуйста, поставьте ваш багаж здесь.","vi":"Vui lòng để lại hành lý của bạn ở đây.","fa":"لطفا چمدان خود را اینجا بگذارید."},{"de":"Am Flughafen haben wir unser Gepäck verloren.","en":"We lost our luggage at the airport.","ru":"В аэропорту мы потеряли свой багаж.","vi":"Chúng tôi bị mất hành lý ở sân bay.","fa":"چمدانمان را در فرودگاه گم کردیم."}]},{"word":"das Gepäck aufgeben","en":"to check in luggage","ru":"сдавать багаж","vi":"kiểm tra hành lý","fa":"چمدان را چک کنید","examples":[{"de":"Am Flughafen müssen wir zuerst das Gepäck aufgeben.","en":"At the airport we first have to check in the luggage.","ru":"В аэропорту нам сначала нужно сдать багаж.","vi":"Tại sân bay chúng ta phải kiểm tra hành lý trước.","fa":"در فرودگاه ابتدا باید چمدان خود را تحویل بگیریم."},{"de":"Sie gab ihren Koffer am Schalter auf.","en":"She checked in her suitcase at the counter.","ru":"Она сдала свой чемодан у стойки.","vi":"Cô kiểm tra va li của mình tại quầy.","fa":"چمدانش را در پیشخوان چک کرد."},{"de":"Hast du das Gepäck schon aufgegeben?","en":"Have you already checked in the luggage?","ru":"Ты уже сдал багаж?","vi":"Bạn đã kiểm tra hành lý của mình chưa?","fa":"آیا هنوز چمدان خود را چک کرده اید؟"}]},{"word":"die Gepäckausgabe","en":"baggage claim, baggage reclaim","ru":"выдача багажа, зона получения багажа","vi":"yêu cầu hành lý","fa":"the baggage claim","examples":[{"de":"Wir warteten lange an der Gepäckausgabe auf unsere Koffer.","en":"We waited a long time at the baggage claim for our suitcases.","ru":"Мы долго ждали свои чемоданы у выдачи багажа.","vi":"Chúng tôi đã đợi rất lâu ở quầy lấy hành lý để lấy hành lý.","fa":"مدت زیادی در محل بارگیری چمدان‌هایمان منتظر ماندیم."},{"de":"Die Gepäckausgabe befindet sich im Erdgeschoss.","en":"The baggage reclaim is on the ground floor.","ru":"Выдача багажа находится на первом этаже.","vi":"Khu nhận hành lý nằm ở tầng trệt.","fa":"تحویل بار در طبقه همکف است."},{"de":"Mein Koffer kam nicht an der Gepäckausgabe an.","en":"My suitcase did not arrive at the baggage claim.","ru":"Мой чемодан не прибыл на выдачу багажа.","vi":"Vali của tôi không đến nơi nhận hành lý.","fa":"چمدان من در زمان تحویل بار نرسید."}]},{"word":"gerade","en":"straight; just, right now","ru":"прямой; как раз, сейчас","vi":"thẳng","fa":"مستقیم","examples":[{"de":"Zeichne eine gerade Linie auf das Blatt.","en":"Draw a straight line on the sheet.","ru":"Нарисуй прямую линию на листе.","vi":"Vẽ một đường thẳng trên tờ giấy.","fa":"یک خط مستقیم روی برگه بکشید."},{"de":"Ich bin gerade beim Kochen.","en":"I'm cooking right now.","ru":"Я как раз готовлю.","vi":"Bây giờ tôi đang nấu ăn.","fa":"من الان دارم آشپزی میکنم"}]},{"word":"das Gerät","en":"device, appliance","ru":"прибор, устройство","vi":"thiết bị","fa":"دستگاه","examples":[{"de":"Dieses Gerät spart viel Strom.","en":"This device saves a lot of electricity.","ru":"Этот прибор экономит много электроэнергии.","vi":"Thiết bị này tiết kiệm rất nhiều điện năng.","fa":"این دستگاه در مصرف برق بسیار صرفه جویی می کند."},{"de":"Das neue Gerät ist leider kaputt.","en":"Unfortunately the new device is broken.","ru":"К сожалению, новый прибор сломан.","vi":"Thật không may, thiết bị mới bị hỏng.","fa":"متاسفانه دستگاه جدید خراب است."}]},{"word":"gerecht","en":"fair, just","ru":"справедливый","vi":"công bằng","fa":"منصفانه","examples":[{"de":"Der Lehrer behandelt alle Schüler gerecht.","en":"The teacher treats all students fairly.","ru":"Учитель справедливо относится ко всем ученикам.","vi":"Giáo viên đối xử công bằng với tất cả học sinh.","fa":"معلم با همه دانش آموزان منصفانه رفتار می کند."},{"de":"Das Urteil wurde von vielen als nicht gerecht empfunden.","en":"The verdict was seen by many as not fair.","ru":"Многие сочли приговор несправедливым.","vi":"Nhiều người cho rằng bản án này không công bằng.","fa":"این حکم از نظر بسیاری ناعادلانه بود."}]},{"word":"die Gerechtigkeit","en":"justice; fairness","ru":"справедливость","vi":"công lý","fa":"عدالت","examples":[{"de":"Er kämpft für mehr Gerechtigkeit in der Gesellschaft.","en":"He fights for more justice in society.","ru":"Он борется за большую справедливость в обществе.","vi":"Anh đấu tranh cho sự công bằng hơn trong xã hội.","fa":"او برای عدالت بیشتر در جامعه مبارزه می کند."},{"de":"Kinder haben ein feines Gespür für Gerechtigkeit.","en":"Children have a keen sense of fairness.","ru":"У детей тонкое чувство справедливости.","vi":"Trẻ em có ý thức sâu sắc về công lý.","fa":"کودکان حس عدالت خواهی شدیدی دارند."}]},{"word":"geregelt","en":"regulated, settled, orderly","ru":"упорядоченный, налаженный, отрегулированный","vi":"quy định","fa":"تنظیم شده است","examples":[{"de":"Ich habe einen geregelten Arbeitsalltag.","en":"I have a regular daily work routine.","ru":"У меня налаженный рабочий распорядок дня.","vi":"Tôi có một lịch trình làm việc đều đặn.","fa":"من یک برنامه کاری منظم دارم."},{"de":"Die Zuständigkeiten sind klar geregelt.","en":"The responsibilities are clearly regulated.","ru":"Обязанности чётко распределены.","vi":"Trách nhiệm được quy định rõ ràng.","fa":"مسئولیت ها به وضوح تنظیم شده است."},{"de":"Endlich ist alles geregelt und ich kann entspannen.","en":"Everything is finally settled and I can relax.","ru":"Всё наконец улажено, и я могу расслабиться.","vi":"Cuối cùng mọi thứ đã được giải quyết và tôi có thể thư giãn.","fa":"بالاخره همه چیز حل شد و من می توانم آرامش داشته باشم."}]},{"word":"das Gericht","en":"court (of law); dish (food)","ru":"суд; блюдо (еда)","vi":"tòa án","fa":"دادگاه","examples":[{"de":"Der Fall wird vor Gericht verhandelt.","en":"The case is being tried in court.","ru":"Дело рассматривается в суде.","vi":"Vụ án đang được xét xử tại tòa án.","fa":"این پرونده در دادگاه در حال رسیدگی است."},{"de":"Das Restaurant bietet vegetarische Gerichte an.","en":"The restaurant offers vegetarian dishes.","ru":"Ресторан предлагает вегетарианские блюда.","vi":"Nhà hàng cung cấp các món ăn chay.","fa":"این رستوران غذاهای گیاهی ارائه می دهد."}]},{"word":"gering","en":"small, slight","ru":"незначительный, малый","vi":"thấp","fa":"پایین","examples":[{"de":"Die Wahrscheinlichkeit für Regen ist heute gering.","en":"The probability of rain is low today.","ru":"Вероятность дождя сегодня невелика.","vi":"Khả năng mưa hôm nay là thấp.","fa":"احتمال بارندگی امروز کم است."},{"de":"Er hat nur geringe Kenntnisse in Englisch.","en":"He has only limited knowledge of English.","ru":"У него лишь незначительные знания английского.","vi":"Anh ấy có rất ít kiến ​​thức về tiếng Anh.","fa":"او دانش کمی از زبان انگلیسی دارد."}]},{"word":"gern/gerne","en":"gladly, with pleasure","ru":"охотно, с удовольствием","vi":"vui vẻ/vui lòng","fa":"با خوشحالی/خوشحالی","examples":[{"de":"Ich helfe dir gern bei den Hausaufgaben.","en":"I'll gladly help you with your homework.","ru":"Я с удовольствием помогу тебе с домашним заданием.","vi":"Tôi rất vui được giúp bạn làm bài tập về nhà.","fa":"خوشحال می شوم در انجام تکالیف به شما کمک کنم."},{"de":"Sie trinkt gerne Kaffee am Morgen.","en":"She likes to drink coffee in the morning.","ru":"Она любит пить кофе по утрам.","vi":"Cô ấy thích uống cà phê vào buổi sáng.","fa":"او دوست دارد صبح ها قهوه بنوشد."}]},{"word":"das Gerücht","en":"rumour","ru":"слух","vi":"tin đồn","fa":"شایعه","examples":[{"de":"Es geht das Gerücht, dass die Firma schließt.","en":"There's a rumour going around that the company is closing.","ru":"Ходит слух, что компания закрывается.","vi":"Có tin đồn công ty sắp đóng cửa.","fa":"شایعه ای مبنی بر تعطیلی این شرکت وجود دارد."},{"de":"Glaub nicht jedes Gerücht, das du hörst.","en":"Don't believe every rumour you hear.","ru":"Не верь каждому слуху, который слышишь.","vi":"Đừng tin vào mọi tin đồn bạn nghe được.","fa":"هر شایعه ای که می شنوید را باور نکنید."}]},{"word":"gesamt","en":"entire, total, whole","ru":"весь, целый, общий, совокупный","vi":"tổng cộng","fa":"کل","examples":[{"de":"Die gesamte Mannschaft hat hart trainiert.","en":"The entire team trained hard.","ru":"Вся команда усердно тренировалась.","vi":"Toàn đội đã tập luyện chăm chỉ.","fa":"کل تیم سخت تمرین کردند."},{"de":"Wie hoch sind die gesamten Kosten?","en":"How high are the total costs?","ru":"Насколько велики общие расходы?","vi":"Tổng chi phí là bao nhiêu?","fa":"کل هزینه ها چقدر است؟"},{"de":"Das betrifft die gesamte Bevölkerung des Landes.","en":"This affects the entire population of the country.","ru":"Это касается всего населения страны.","vi":"Điều này ảnh hưởng đến toàn bộ dân số của đất nước.","fa":"این بر کل جمعیت کشور تأثیر می گذارد."}]},{"word":"gesamt-","en":"total, whole, entire (prefix)","ru":"общий, весь (приставка)","vi":"tổng cộng","fa":"کل","examples":[{"de":"Der Gesamtbetrag der Rechnung beträgt 250 Euro.","en":"The total amount of the bill is 250 euros.","ru":"Общая сумма счёта составляет 250 евро.","vi":"Tổng số tiền của hóa đơn là 250 euro.","fa":"مبلغ کل صورتحساب 250 یورو است."},{"de":"Die Gesamtkosten für die Reise waren höher als erwartet.","en":"The total costs for the trip were higher than expected.","ru":"Общая стоимость поездки оказалась выше ожидаемой.","vi":"Tổng chi phí của chuyến đi cao hơn dự kiến.","fa":"هزینه کل سفر بیشتر از حد انتظار بود."}]},{"word":"das Geschäft","en":"shop, store; business","ru":"магазин; дело, бизнес","vi":"việc kinh doanh","fa":"کسب و کار","examples":[{"de":"Das Geschäft an der Ecke verkauft frisches Brot.","en":"The shop on the corner sells fresh bread.","ru":"Магазин на углу продаёт свежий хлеб.","vi":"Cửa hàng ở góc phố bán bánh mì tươi.","fa":"مغازه آن گوشه نان تازه می فروشد."},{"de":"Er macht gute Geschäfte mit ausländischen Firmen.","en":"He does good business with foreign companies.","ru":"Он ведёт успешные дела с зарубежными фирмами.","vi":"Anh ấy làm ăn tốt với các công ty nước ngoài.","fa":"او تجارت خوبی با شرکت های خارجی انجام می دهد."}]},{"word":"geschehen","en":"to happen","ru":"происходить, случаться","vi":"xảy ra","fa":"اتفاق بیفتد","examples":[{"de":"Bei dem Unfall ist zum Glück nichts Schlimmes geschehen.","en":"Fortunately, nothing bad happened in the accident.","ru":"К счастью, при аварии ничего страшного не произошло.","vi":"Rất may không có điều gì đáng tiếc xảy ra trong vụ tai nạn.","fa":"خوشبختانه اتفاق بدی در این تصادف رخ نداد."},{"de":"Wie konnte das nur geschehen?","en":"How could this have happened?","ru":"Как такое вообще могло случиться?","vi":"Làm thế nào điều này có thể xảy ra?","fa":"چگونه ممکن است این اتفاق بیفتد؟"}]},{"word":"das Geschenk","en":"gift, present","ru":"подарок","vi":"món quà","fa":"هدیه","examples":[{"de":"Zum Geburtstag hat sie ein schönes Geschenk bekommen.","en":"She received a nice gift for her birthday.","ru":"На день рождения она получила красивый подарок.","vi":"Cô ấy đã nhận được một món quà tuyệt vời vào ngày sinh nhật của mình.","fa":"او برای تولدش یک هدیه خوب گرفت."},{"de":"Ich muss noch ein Geschenk für die Hochzeit kaufen.","en":"I still need to buy a gift for the wedding.","ru":"Мне ещё нужно купить подарок на свадьбу.","vi":"Tôi vẫn phải mua một món quà cho đám cưới.","fa":"هنوز باید برای عروسی هدیه بخرم."}]},{"word":"die Geschichte","en":"story; history","ru":"история (рассказ; наука)","vi":"câu chuyện","fa":"داستان","examples":[{"de":"Die Großmutter erzählt den Kindern eine Geschichte.","en":"The grandmother tells the children a story.","ru":"Бабушка рассказывает детям историю.","vi":"Bà nội kể cho trẻ nghe một câu chuyện.","fa":"مادربزرگ برای بچه ها قصه تعریف می کند."},{"de":"In der Schule lernen wir die Geschichte Europas.","en":"At school we learn about the history of Europe.","ru":"В школе мы изучаем историю Европы.","vi":"Ở trường chúng tôi học lịch sử của Châu Âu.","fa":"در مدرسه تاریخ اروپا را یاد می گیریم."}]},{"word":"die Geschichtsstunde","en":"history lesson","ru":"урок истории","vi":"bài học lịch sử","fa":"درس تاریخ","examples":[{"de":"In der Geschichtsstunde sprachen wir über das Mittelalter.","en":"In the history lesson we talked about the Middle Ages.","ru":"На уроке истории мы говорили о Средневековье.","vi":"Trong lớp lịch sử chúng tôi đã nói về thời Trung Cổ.","fa":"در کلاس تاریخ در مورد قرون وسطی صحبت کردیم."},{"de":"Die Geschichtsstunde war heute besonders spannend.","en":"The history lesson was especially exciting today.","ru":"Урок истории сегодня был особенно увлекательным.","vi":"Tiết học lịch sử hôm nay đặc biệt thú vị.","fa":"درس تاریخ امروز بسیار هیجان انگیز بود."},{"de":"Unser Lehrer macht jede Geschichtsstunde lebendig.","en":"Our teacher makes every history lesson come alive.","ru":"Наш учитель делает каждый урок истории живым.","vi":"Giáo viên của chúng tôi làm cho mọi bài học lịch sử trở nên sống động.","fa":"معلم ما هر درس تاریخ را زنده می کند."}]},{"word":"geschieden","en":"divorced","ru":"разведённый","vi":"đã ly hôn","fa":"طلاق گرفته","examples":[{"de":"Meine Eltern sind seit fünf Jahren geschieden.","en":"My parents have been divorced for five years.","ru":"Мои родители в разводе уже пять лет.","vi":"Bố mẹ tôi đã ly hôn được năm năm.","fa":"پدر و مادرم پنج سال است که از هم جدا شده اند."},{"de":"Sie ist geschieden und hat zwei Kinder.","en":"She is divorced and has two children.","ru":"Она разведена и у неё двое детей.","vi":"Cô đã ly hôn và có hai con.","fa":"او طلاق گرفته و دو فرزند دارد."}]},{"word":"das Geschirr","en":"dishes, crockery","ru":"посуда","vi":"các món ăn","fa":"ظروف","examples":[{"de":"Nach dem Essen muss noch das Geschirr gespült werden.","en":"After the meal, the dishes still need to be washed.","ru":"После еды ещё нужно вымыть посуду.","vi":"Ăn xong vẫn phải rửa bát.","fa":"پس از صرف غذا، ظروف هنوز باید شسته شوند."},{"de":"Das schmutzige Geschirr steht in der Spüle.","en":"The dirty dishes are in the sink.","ru":"Грязная посуда стоит в раковине.","vi":"Bát đĩa bẩn đang ở trong bồn rửa.","fa":"ظرف های کثیف داخل سینک هستند."}]},{"word":"der Geschirrschrank","en":"crockery cupboard","ru":"буфет, шкаф для посуды","vi":"cái tủ","fa":"کمد","examples":[{"de":"Die Teller stehen im Geschirrschrank oben rechts.","en":"The plates are in the crockery cupboard at the top right.","ru":"Тарелки стоят в шкафу для посуды вверху справа.","vi":"Những chiếc đĩa nằm trong tủ phía trên bên phải.","fa":"بشقاب ها در کمد بالا سمت راست هستند."},{"de":"Räum bitte die Tassen in den Geschirrschrank.","en":"Please put the cups away in the crockery cupboard.","ru":"Убери, пожалуйста, чашки в шкаф для посуды.","vi":"Vui lòng đặt những chiếc cốc vào tủ.","fa":"لطفا فنجان ها را در کمد بگذارید."},{"de":"Der Geschirrschrank ist viel zu voll.","en":"The crockery cupboard is far too full.","ru":"Шкаф для посуды слишком переполнен.","vi":"Cái tủ đã đầy quá rồi.","fa":"کمد خیلی پر شده"}]},{"word":"das Geschlecht","en":"gender, sex","ru":"пол (мужской/женский)","vi":"giới tính","fa":"جنسیت","examples":[{"de":"Auf dem Formular muss man sein Geschlecht angeben.","en":"You have to state your gender on the form.","ru":"В анкете нужно указать свой пол.","vi":"Bạn phải cho biết giới tính của mình trên mẫu đơn.","fa":"شما باید جنسیت خود را در فرم مشخص کنید."},{"de":"Das Geschlecht des Babys ist noch unbekannt.","en":"The baby's gender is not yet known.","ru":"Пол ребёнка пока неизвестен.","vi":"Giới tính của em bé vẫn chưa được biết.","fa":"جنسیت نوزاد هنوز مشخص نیست."}]},{"word":"der Geschmack","en":"taste","ru":"вкус","vi":"hương vị","fa":"طعم","examples":[{"de":"Die Suppe hat einen sehr würzigen Geschmack.","en":"The soup has a very spicy taste.","ru":"У супа очень пряный вкус.","vi":"Súp có vị rất cay.","fa":"سوپ طعم بسیار تند دارد."},{"de":"Der Kuchen ist zwar hübsch, aber der Geschmack überzeugt mich nicht.","en":"The cake looks nice, but the taste doesn't convince me.","ru":"Торт выглядит красиво, но вкус меня не убеждает.","vi":"Bánh đẹp nhưng mình không ấn tượng lắm về mùi vị.","fa":"کیک زیباست اما طعمش تحت تاثیر قرار نگرفتم."}]},{"word":"die Geschmacksrichtung","en":"flavour","ru":"вкус (сорт, разновидность вкуса)","vi":"hương vị","fa":"طعم","examples":[{"de":"Welche Geschmacksrichtung möchtest du beim Eis?","en":"Which flavour would you like for the ice cream?","ru":"Какой вкус мороженого ты хочешь?","vi":"Bạn muốn hương vị kem nào?","fa":"چه طعمی از بستنی می خواهید؟"},{"de":"Das Getränk gibt es in fünf Geschmacksrichtungen.","en":"The drink comes in five flavours.","ru":"Напиток бывает пяти вкусов.","vi":"Đồ uống có năm hương vị.","fa":"این نوشیدنی در پنج طعم عرضه می شود."},{"de":"Meine Lieblingsgeschmacksrichtung ist Zitrone.","en":"My favourite flavour is lemon.","ru":"Мой любимый вкус — лимон.","vi":"Hương vị yêu thích của tôi là chanh.","fa":"طعم مورد علاقه من لیمو است."}]},{"word":"die Geschwindigkeit","en":"speed","ru":"скорость","vi":"tốc độ","fa":"سرعت","examples":[{"de":"Die erlaubte Geschwindigkeit in der Stadt beträgt 50 km/h.","en":"The permitted speed in the city is 50 km/h.","ru":"Разрешённая скорость в городе составляет 50 км/ч.","vi":"Tốc độ cho phép trong thành phố là 50 km/h.","fa":"سرعت مجاز در شهر 50 کیلومتر بر ساعت است."},{"de":"Das Auto fuhr mit hoher Geschwindigkeit an uns vorbei.","en":"The car drove past us at high speed.","ru":"Машина проехала мимо нас на высокой скорости.","vi":"Chiếc xe vượt qua chúng tôi với tốc độ cao.","fa":"ماشین با سرعت زیاد از کنار ما گذشت."}]},{"word":"die Geschwindigkeitsbeschränkung","en":"speed limit","ru":"ограничение скорости","vi":"giới hạn tốc độ","fa":"محدودیت سرعت","examples":[{"de":"In der Stadt gilt eine Geschwindigkeitsbeschränkung von fünfzig.","en":"In town there is a speed limit of fifty.","ru":"В городе действует ограничение скорости пятьдесят.","vi":"Có giới hạn tốc độ là năm mươi trong thành phố.","fa":"سرعت مجاز در شهر پنجاه است."},{"de":"Er hat die Geschwindigkeitsbeschränkung überschritten.","en":"He exceeded the speed limit.","ru":"Он превысил ограничение скорости.","vi":"Anh ta đã vượt quá tốc độ cho phép.","fa":"او از سرعت مجاز فراتر رفت."},{"de":"Wegen der Baustelle gibt es eine neue Geschwindigkeitsbeschränkung.","en":"Because of the roadworks there is a new speed limit.","ru":"Из-за стройки введено новое ограничение скорости.","vi":"Do công trường đang xây dựng nên có giới hạn tốc độ mới.","fa":"با توجه به محل ساخت و ساز محدودیت سرعت جدید وجود دارد."}]},{"word":"die Geschwister","en":"siblings","ru":"братья и сёстры","vi":"anh chị em","fa":"خواهر و برادر","examples":[{"de":"Ich habe zwei Geschwister, einen Bruder und eine Schwester.","en":"I have two siblings, a brother and a sister.","ru":"У меня двое братьев и сестёр — брат и сестра.","vi":"Tôi có hai anh chị em, một anh trai và một em gái.","fa":"من دو خواهر و برادر دارم، یک برادر و یک خواهر."},{"de":"Hast du Geschwister oder bist du Einzelkind?","en":"Do you have siblings or are you an only child?","ru":"У тебя есть братья или сёстры, или ты единственный ребёнок?","vi":"Bạn có anh chị em ruột hay bạn là con một?","fa":"آیا شما خواهر و برادر دارید یا تک فرزند هستید؟"}]},{"word":"gesellig","en":"sociable, convivial","ru":"общительный, компанейский","vi":"hòa đồng","fa":"اجتماعی","examples":[{"de":"Sie ist ein sehr geselliger Mensch.","en":"She is a very sociable person.","ru":"Она очень общительный человек.","vi":"Cô ấy là một người rất hòa đồng.","fa":"او فردی بسیار اجتماعی است."},{"de":"Wir hatten einen geselligen Abend mit Freunden.","en":"We had a convivial evening with friends.","ru":"У нас был приятный вечер в компании друзей.","vi":"Chúng tôi đã có một buổi tối hòa đồng với bạn bè.","fa":"یک شب اجتماعی با دوستان داشتیم."},{"de":"Beim Grillen geht es immer sehr gesellig zu.","en":"Barbecues are always very sociable.","ru":"Барбекю всегда проходит очень весело и в компании.","vi":"Tiệc nướng luôn rất hòa đồng.","fa":"کباب کردن همیشه بسیار اجتماعی است."}]},{"word":"die Gesellschaft","en":"society; company","ru":"общество; компания","vi":"xã hội","fa":"جامعه","examples":[{"de":"Die moderne Gesellschaft verändert sich schnell.","en":"Modern society is changing quickly.","ru":"Современное общество быстро меняется.","vi":"Xã hội hiện đại đang thay đổi nhanh chóng.","fa":"جامعه مدرن به سرعت در حال تغییر است."},{"de":"Er leistet ihr gerne Gesellschaft am Abend.","en":"He gladly keeps her company in the evening.","ru":"Он с удовольствием составляет ей компанию вечером.","vi":"Anh ấy thích bầu bạn với cô ấy vào buổi tối.","fa":"او دوست دارد عصرها با او همراهی کند."}]},{"word":"gesellschaftlich","en":"social; societal","ru":"общественный, социальный","vi":"xã hội","fa":"اجتماعی","examples":[{"de":"Das ist ein wichtiges gesellschaftliches Problem.","en":"That is an important societal problem.","ru":"Это важная общественная проблема.","vi":"Đây là một vấn đề xã hội quan trọng.","fa":"این یک مشکل اجتماعی مهم است."},{"de":"Gesellschaftliche Veränderungen brauchen Zeit.","en":"Societal changes take time.","ru":"Общественные изменения требуют времени.","vi":"Những thay đổi xã hội cần có thời gian.","fa":"تغییرات اجتماعی زمان می برد."},{"de":"Sie engagiert sich gesellschaftlich für Geflüchtete.","en":"She is socially engaged on behalf of refugees.","ru":"Она ведёт общественную работу с беженцами.","vi":"Cô ấy cam kết xã hội với người tị nạn.","fa":"او از نظر اجتماعی به پناهندگان متعهد است."}]},{"word":"das Gesetz","en":"law","ru":"закон","vi":"luật pháp","fa":"قانون","examples":[{"de":"In diesem Land gilt ein strenges Gesetz gegen Rauchen.","en":"There is a strict law against smoking in this country.","ru":"В этой стране действует строгий закон против курения.","vi":"Đất nước này có luật nghiêm khắc chống lại việc hút thuốc.","fa":"این کشور قانون سختگیرانه ای برای مبارزه با استعمال دخانیات دارد."},{"de":"Das neue Gesetz tritt nächsten Monat in Kraft.","en":"The new law comes into force next month.","ru":"Новый закон вступает в силу в следующем месяце.","vi":"Luật mới sẽ có hiệu lực vào tháng tới.","fa":"قانون جدید از ماه آینده اجرایی می شود."}]},{"word":"die Gesetzesänderung","en":"amendment to the law","ru":"изменение закона, поправка к закону","vi":"sự thay đổi của pháp luật","fa":"تغییر در قانون","examples":[{"de":"Die Gesetzesänderung wurde vom Parlament beschlossen.","en":"The amendment was passed by parliament.","ru":"Поправку к закону приняли в парламенте.","vi":"Sự thay đổi trong luật đã được Quốc hội thông qua.","fa":"این قانون در مجلس تصویب شد."},{"de":"Über die Gesetzesänderung wird heftig diskutiert.","en":"The amendment to the law is being heatedly debated.","ru":"Изменение закона бурно обсуждается.","vi":"Có cuộc tranh luận sôi nổi về sự thay đổi trong luật.","fa":"بحث های داغ در مورد تغییر قانون وجود دارد."},{"de":"Die Gesetzesänderung betrifft alle Autofahrer.","en":"The amendment affects all motorists.","ru":"Изменение закона касается всех автомобилистов.","vi":"Sự thay đổi trong luật ảnh hưởng đến tất cả các tài xế.","fa":"تغییر قانون همه رانندگان را تحت تاثیر قرار می دهد."}]},{"word":"gesetzlich","en":"legal; statutory","ru":"законный; установленный законом","vi":"hợp pháp","fa":"قانونی","examples":[{"de":"Der gesetzliche Urlaub beträgt mindestens 20 Tage.","en":"The statutory holiday entitlement is at least 20 days.","ru":"Установленный законом отпуск составляет не менее 20 дней.","vi":"Kỳ nghỉ theo luật định ít nhất là 20 ngày.","fa":"مرخصی قانونی حداقل 20 روز است."},{"de":"Rauchen ist an diesem Ort gesetzlich verboten.","en":"Smoking is prohibited by law in this place.","ru":"Курение в этом месте запрещено законом.","vi":"Pháp luật cấm hút thuốc ở địa điểm này.","fa":"سیگار کشیدن در این مکان طبق قانون ممنوع است."}]},{"word":"das Gesicht","en":"face","ru":"лицо","vi":"khuôn mặt","fa":"صورت","examples":[{"de":"Sie hat ein freundliches Gesicht.","en":"She has a friendly face.","ru":"У неё дружелюбное лицо.","vi":"Cô ấy có khuôn mặt thân thiện.","fa":"او چهره ای دوستانه دارد."},{"de":"Er wusch sich das Gesicht mit kaltem Wasser.","en":"He washed his face with cold water.","ru":"Он умыл лицо холодной водой.","vi":"Anh rửa mặt bằng nước lạnh.","fa":"صورتش را با آب سرد شست."}]},{"word":"gespannt","en":"curious, eager","ru":"заинтригованный, с нетерпением ожидающий","vi":"vui mừng","fa":"هیجان زده","examples":[{"de":"Ich bin gespannt, wie das Spiel ausgeht.","en":"I'm curious how the game will turn out.","ru":"Мне интересно, чем закончится игра.","vi":"Tôi rất phấn khích để xem trò chơi diễn ra như thế nào.","fa":"من هیجان زده هستم که ببینم بازی چگونه پیش می رود."},{"de":"Die Kinder waren gespannt auf ihre Geschenke.","en":"The children were eager for their presents.","ru":"Дети с нетерпением ждали своих подарков.","vi":"Các em hào hứng với phần quà của mình.","fa":"بچه ها از هدیه هایشان هیجان زده بودند."}]},{"word":"das Gespräch","en":"conversation","ru":"разговор, беседа","vi":"cuộc trò chuyện","fa":"گفتگو","examples":[{"de":"Wir hatten ein langes Gespräch über die Zukunft.","en":"We had a long conversation about the future.","ru":"У нас был долгий разговор о будущем.","vi":"Chúng tôi đã có một cuộc trò chuyện dài về tương lai.","fa":"گفتگوی طولانی در مورد آینده داشتیم."},{"de":"Kann ich Sie kurz für ein Gespräch stören?","en":"May I briefly bother you for a conversation?","ru":"Могу я вас ненадолго отвлечь для разговора?","vi":"Tôi có thể làm phiền bạn một chút để trò chuyện được không?","fa":"آیا می توانم برای چت کردن یک لحظه مزاحم شما شوم؟"}]},{"word":"gestattet","en":"permitted, allowed","ru":"разрешённый, дозволенный","vi":"được phép","fa":"مجاز است","examples":[{"de":"Rauchen ist hier nicht gestattet.","en":"Smoking is not permitted here.","ru":"Курить здесь не разрешено.","vi":"Hút thuốc không được phép ở đây.","fa":"سیگار کشیدن در اینجا ممنوع است."},{"de":"Hunde sind im Restaurant nicht gestattet.","en":"Dogs are not allowed in the restaurant.","ru":"Собак в ресторан не пускают.","vi":"Chó không được phép vào nhà hàng.","fa":"ورود سگ به رستوران ممنوع است."},{"de":"Es ist gestattet, während der Pause zu telefonieren.","en":"It is permitted to make phone calls during the break.","ru":"Во время перерыва разрешено разговаривать по телефону.","vi":"Được phép gọi điện thoại trong giờ giải lao.","fa":"تماس تلفنی در زمان استراحت مجاز است."}]},{"word":"gestehen","en":"to confess","ru":"признаваться; сознаваться","vi":"thú nhận","fa":"اعتراف کردن","examples":[{"de":"Der Täter gestand die Tat vor Gericht.","en":"The perpetrator confessed to the crime in court.","ru":"Преступник сознался в содеянном в суде.","vi":"Thủ phạm đã thừa nhận hành vi phạm tội trước tòa.","fa":"عامل جنایت در دادگاه به جرم خود اعتراف کرد."},{"de":"Ich muss gestehen, dass ich das Buch nie gelesen habe.","en":"I have to confess that I never read the book.","ru":"Должен признаться, что я так и не прочитал эту книгу.","vi":"Tôi phải thừa nhận rằng tôi chưa bao giờ đọc cuốn sách này.","fa":"باید اعتراف کنم که هرگز کتاب را نخوانده ام."}]},{"word":"gestern","en":"yesterday","ru":"вчера","vi":"hôm qua","fa":"دیروز","examples":[{"de":"Gestern habe ich meine alte Freundin getroffen.","en":"Yesterday I met my old friend.","ru":"Вчера я встретил свою старую подругу.","vi":"Hôm qua tôi đã gặp lại người bạn cũ của tôi.","fa":"دیروز با دوست قدیمی ام آشنا شدم."},{"de":"Gestern Abend war ich im Kino.","en":"Yesterday evening I was at the cinema.","ru":"Вчера вечером я был в кино.","vi":"Tôi đã đi xem phim tối qua.","fa":"دیشب رفتم سینما."}]},{"word":"gestresst","en":"stressed (out)","ru":"напряжённый, в состоянии стресса","vi":"nhấn mạnh","fa":"تاکید کرد","examples":[{"de":"Nach der langen Woche bin ich völlig gestresst.","en":"After the long week I am completely stressed out.","ru":"После долгой недели я совершенно вымотан.","vi":"Sau một tuần dài tôi hoàn toàn căng thẳng.","fa":"بعد از یک هفته طولانی کاملا استرس دارم."},{"de":"Sie wirkt in letzter Zeit ziemlich gestresst.","en":"She has seemed quite stressed lately.","ru":"В последнее время она выглядит довольно напряжённой.","vi":"Gần đây cô ấy có vẻ khá căng thẳng.","fa":"به نظر می رسد او اخیراً استرس زیادی دارد."},{"de":"Wenn ich gestresst bin, mache ich gern Yoga.","en":"When I am stressed I like to do yoga.","ru":"Когда я в стрессе, я люблю заниматься йогой.","vi":"Khi tôi căng thẳng, tôi thích tập yoga.","fa":"وقتی استرس دارم، دوست دارم یوگا انجام دهم."}]},{"word":"gesund","en":"healthy","ru":"здоровый","vi":"khỏe mạnh","fa":"سالم","examples":[{"de":"Obst und Gemüse sind sehr gesund.","en":"Fruit and vegetables are very healthy.","ru":"Фрукты и овощи очень полезны для здоровья.","vi":"Trái cây và rau quả rất tốt cho sức khỏe.","fa":"میوه ها و سبزیجات بسیار سالم هستند."},{"de":"Nach der Grippe fühlt er sich wieder gesund.","en":"After the flu, he feels healthy again.","ru":"После гриппа он снова чувствует себя здоровым.","vi":"Sau cơn cúm, anh ấy cảm thấy khỏe mạnh trở lại.","fa":"بعد از آنفولانزا دوباره احساس سلامتی می کند."}]},{"word":"die Gesundheit","en":"health","ru":"здоровье","vi":"sức khỏe","fa":"سلامتی","examples":[{"de":"Gesundheit ist wichtiger als Geld.","en":"Health is more important than money.","ru":"Здоровье важнее денег.","vi":"Sức khỏe quan trọng hơn tiền bạc.","fa":"سلامتی مهمتر از پول است."},{"de":"Sport ist gut für die Gesundheit.","en":"Sport is good for your health.","ru":"Спорт полезен для здоровья.","vi":"Thể thao tốt cho sức khỏe của bạn.","fa":"ورزش برای سلامتی شما مفید است."}]},{"word":"das Gesundheitszeugnis","en":"health certificate","ru":"медицинская справка, санитарная книжка","vi":"giấy chứng nhận sức khoẻ","fa":"the health certificate","examples":[{"de":"Für diese Arbeit braucht man ein Gesundheitszeugnis.","en":"For this job you need a health certificate.","ru":"Для этой работы нужна медицинская справка.","vi":"Đối với công việc này, bạn cần có giấy chứng nhận sức khoẻ.","fa":"برای این کار به گواهی سلامت نیاز دارید."},{"de":"Das Gesundheitszeugnis stellt der Arzt aus.","en":"The doctor issues the health certificate.","ru":"Медицинскую справку выдаёт врач.","vi":"Bác sĩ cấp giấy chứng nhận sức khỏe.","fa":"پزشک گواهی سلامت صادر می کند."},{"de":"Ohne gültiges Gesundheitszeugnis darf er nicht in der Küche arbeiten.","en":"Without a valid health certificate he is not allowed to work in the kitchen.","ru":"Без действующей медицинской справки ему нельзя работать на кухне.","vi":"Anh ta không được phép làm việc trong bếp nếu không có giấy chứng nhận sức khỏe hợp lệ.","fa":"او مجاز به کار در آشپزخانه بدون گواهی سلامت معتبر نیست."}]},{"word":"das Getränk","en":"drink, beverage","ru":"напиток","vi":"đồ uống","fa":"نوشیدنی","examples":[{"de":"Welche Getränke möchten Sie bestellen?","en":"Which drinks would you like to order?","ru":"Какие напитки вы хотите заказать?","vi":"Bạn muốn gọi đồ uống nào?","fa":"کدام نوشیدنی را دوست دارید سفارش دهید؟"},{"de":"Im Sommer trinke ich gerne kalte Getränke.","en":"In summer I like to drink cold beverages.","ru":"Летом я люблю пить холодные напитки.","vi":"Vào mùa hè tôi thích uống đồ uống lạnh.","fa":"در تابستان دوست دارم نوشیدنی های سرد بنوشم."}]},{"word":"die Getränkeauswahl","en":"selection of drinks","ru":"выбор напитков, ассортимент напитков","vi":"việc lựa chọn đồ uống","fa":"انتخاب نوشیدنی","examples":[{"de":"Im Café ist die Getränkeauswahl wirklich groß.","en":"In the café the selection of drinks is really large.","ru":"В кафе действительно большой выбор напитков.","vi":"Việc lựa chọn đồ uống trong quán cà phê thực sự rất phong phú.","fa":"انتخاب نوشیدنی ها در کافه واقعاً زیاد است."},{"de":"Die Getränkeauswahl auf der Karte hat mich überrascht.","en":"The selection of drinks on the menu surprised me.","ru":"Выбор напитков в меню меня удивил.","vi":"Việc lựa chọn đồ uống trong thực đơn làm tôi ngạc nhiên.","fa":"انتخاب نوشیدنی ها در منو من را شگفت زده کرد."},{"de":"Für die Feier kümmere ich mich um die Getränkeauswahl.","en":"For the party I'll take care of the selection of drinks.","ru":"К празднику я займусь выбором напитков.","vi":"Tôi sẽ lo việc lựa chọn đồ uống cho lễ kỷ niệm.","fa":"من از انتخاب نوشیدنی برای جشن مراقبت خواهم کرد."}]},{"word":"getrennt","en":"separate, separated; (paying) separately","ru":"раздельный, отдельный; (платить) раздельно","vi":"tách ra","fa":"جدا شده است","examples":[{"de":"Wir möchten bitte getrennt bezahlen.","en":"We would like to pay separately, please.","ru":"Мы хотели бы заплатить раздельно, пожалуйста.","vi":"Chúng tôi muốn thanh toán riêng.","fa":"لطفا جداگانه پرداخت کنیم"},{"de":"Die beiden leben seit einem Jahr getrennt.","en":"The two have been living apart for a year.","ru":"Эти двое уже год живут раздельно.","vi":"Hai người đã sống ly thân được một năm.","fa":"این دو یک سال است که به طور جداگانه زندگی می کنند."},{"de":"Müll muss getrennt gesammelt werden.","en":"Waste must be collected separately.","ru":"Мусор нужно собирать раздельно.","vi":"Rác phải được thu gom riêng.","fa":"زباله ها باید جداگانه جمع آوری شوند."}]},{"word":"gewährleisten","en":"to ensure, to guarantee","ru":"обеспечивать, гарантировать","vi":"đảm bảo","fa":"اطمینان حاصل شود","examples":[{"de":"Wir müssen die Sicherheit der Gäste gewährleisten.","en":"We must ensure the safety of the guests.","ru":"Мы должны обеспечить безопасность гостей.","vi":"Chúng ta phải đảm bảo an toàn cho du khách.","fa":"ما باید امنیت مهمانان را تضمین کنیم."},{"de":"Die Firma kann eine schnelle Bearbeitung gewährleisten.","en":"The company can guarantee fast processing.","ru":"Фирма может гарантировать быструю обработку.","vi":"Công ty có thể đảm bảo xử lý nhanh chóng.","fa":"این شرکت می تواند پردازش سریع را تضمین کند."},{"de":"Nur so lässt sich die Qualität gewährleisten.","en":"Only in this way can the quality be ensured.","ru":"Только так можно обеспечить качество.","vi":"Đây là cách duy nhất để đảm bảo chất lượng.","fa":"این تنها راه تضمین کیفیت است."}]},{"word":"die Gewalt","en":"violence, force","ru":"насилие, сила","vi":"bạo lực","fa":"خشونت","examples":[{"de":"In dem Film kommt viel Gewalt vor.","en":"There is a lot of violence in the movie.","ru":"В этом фильме много насилия.","vi":"Có rất nhiều cảnh bạo lực trong phim.","fa":"خشونت در فیلم زیاد است."},{"de":"Die Polizei musste Gewalt anwenden, um die Menge zu kontrollieren.","en":"The police had to use force to control the crowd.","ru":"Полиции пришлось применить силу, чтобы усмирить толпу.","vi":"Cảnh sát đã phải dùng vũ lực để kiểm soát đám đông.","fa":"پلیس مجبور شد برای کنترل جمعیت از زور استفاده کند."}]},{"word":"die Gewerkschaft","en":"trade union","ru":"профсоюз","vi":"công đoàn","fa":"اتحادیه","examples":[{"de":"Die Gewerkschaft kämpft für höhere Löhne.","en":"The trade union is fighting for higher wages.","ru":"Профсоюз борется за повышение зарплаты.","vi":"Công đoàn đang đấu tranh đòi mức lương cao hơn.","fa":"اتحادیه برای افزایش دستمزدها مبارزه می کند."},{"de":"Viele Arbeiter sind Mitglied einer Gewerkschaft.","en":"Many workers are members of a trade union.","ru":"Многие рабочие состоят в профсоюзе.","vi":"Nhiều công nhân là thành viên của công đoàn.","fa":"بسیاری از کارگران عضو اتحادیه هستند."}]},{"word":"das Gewicht","en":"weight","ru":"вес","vi":"trọng lượng","fa":"وزن","examples":[{"de":"Das Gewicht des Koffers darf 20 Kilo nicht überschreiten.","en":"The weight of the suitcase must not exceed 20 kilos.","ru":"Вес чемодана не должен превышать 20 килограммов.","vi":"Trọng lượng của vali không được vượt quá 20 kg.","fa":"وزن چمدان نباید بیشتر از 20 کیلو باشد."},{"de":"Er hat in den letzten Monaten viel Gewicht verloren.","en":"He has lost a lot of weight in the last few months.","ru":"За последние месяцы он сильно похудел.","vi":"Anh ấy đã sụt cân rất nhiều trong vài tháng qua.","fa":"او در چند ماه اخیر وزن زیادی از دست داده است."}]},{"word":"der Gewinn","en":"profit, winnings","ru":"прибыль, выигрыш","vi":"lợi nhuận","fa":"سود","examples":[{"de":"Die Firma hat dieses Jahr einen großen Gewinn gemacht.","en":"The company made a large profit this year.","ru":"В этом году компания получила большую прибыль.","vi":"Công ty đã kiếm được lợi nhuận lớn trong năm nay.","fa":"این شرکت در سال جاری سود زیادی به دست آورد."},{"de":"Den Gewinn aus dem Verkauf teilen wir uns.","en":"We will share the profit from the sale.","ru":"Прибыль от продажи мы поделим.","vi":"Chúng tôi chia sẻ lợi nhuận từ việc bán hàng.","fa":"ما سود حاصل از فروش را تقسیم می کنیم."},{"de":"Mit Aktien kann man Gewinn machen, aber auch verlieren.","en":"You can make a profit with shares, but you can also lose.","ru":"На акциях можно получить прибыль, но можно и потерять.","vi":"Bạn có thể kiếm được lợi nhuận từ cổ phiếu, nhưng bạn cũng có thể thua lỗ.","fa":"شما می توانید با سهام سود کنید، اما می توانید ضرر هم داشته باشید."}]},{"word":"gewinnen","en":"to win","ru":"выигрывать","vi":"thắng","fa":"برنده شوید","examples":[{"de":"Unsere Mannschaft hat das Spiel gewonnen.","en":"Our team won the game.","ru":"Наша команда выиграла игру.","vi":"Đội của chúng tôi đã thắng trò chơi.","fa":"تیم ما برنده بازی شد."},{"de":"Sie hat im Lotto eine große Summe gewonnen.","en":"She won a large sum in the lottery.","ru":"Она выиграла крупную сумму в лотерею.","vi":"Cô ấy đã thắng một số tiền lớn trong cuộc xổ số.","fa":"او مبلغ زیادی را در لاتاری برنده شد."}]},{"word":"das Gewissen","en":"conscience","ru":"совесть","vi":"lương tâm","fa":"وجدان","examples":[{"de":"Er hat ein schlechtes Gewissen, weil er gelogen hat.","en":"He has a guilty conscience because he lied.","ru":"У него нечиста совесть, потому что он солгал.","vi":"Anh cảm thấy có lỗi vì đã nói dối.","fa":"او احساس گناه می کند زیرا دروغ گفته است."},{"de":"Sie handelt immer nach ihrem Gewissen.","en":"She always acts according to her conscience.","ru":"Она всегда поступает по совести.","vi":"Cô luôn hành động theo lương tâm của mình.","fa":"او همیشه طبق وجدان خود عمل می کند."}]},{"word":"das Gewitter","en":"thunderstorm","ru":"гроза","vi":"giông bão","fa":"رعد و برق","examples":[{"de":"Heute Nachmittag zieht ein starkes Gewitter auf.","en":"A strong thunderstorm is approaching this afternoon.","ru":"Сегодня днём приближается сильная гроза.","vi":"Một cơn giông mạnh đang đến gần vào chiều nay.","fa":"رعد و برق شدید امروز بعد از ظهر نزدیک است."},{"de":"Während des Gewitters blieben wir zu Hause.","en":"During the thunderstorm we stayed at home.","ru":"Во время грозы мы оставались дома.","vi":"Chúng tôi ở nhà trong cơn bão.","fa":"موقع طوفان در خانه ماندیم."}]},{"word":"gewöhnen","en":"to get used to","ru":"привыкать","vi":"làm quen với","fa":"عادت کن","examples":[{"de":"Ich muss mich noch an die neue Arbeit gewöhnen.","en":"I still have to get used to the new job.","ru":"Мне ещё нужно привыкнуть к новой работе.","vi":"Tôi vẫn phải làm quen với công việc mới.","fa":"هنوز باید به کار جدید عادت کنم."},{"de":"Kinder gewöhnen sich schnell an eine neue Umgebung.","en":"Children quickly get used to a new environment.","ru":"Дети быстро привыкают к новой обстановке.","vi":"Trẻ nhanh chóng làm quen với môi trường mới.","fa":"کودکان به سرعت به محیط جدید عادت می کنند."}]},{"word":"die Gewohnheit","en":"habit","ru":"привычка","vi":"thói quen","fa":"عادت","examples":[{"de":"Frühes Aufstehen ist bei ihm eine alte Gewohnheit.","en":"Getting up early is an old habit of his.","ru":"Ранний подъём — его давняя привычка.","vi":"Dậy sớm là thói quen cũ của anh.","fa":"زود بیدار شدن برای او یک عادت قدیمی است."},{"de":"Aus Gewohnheit trinkt sie morgens immer Tee.","en":"Out of habit, she always drinks tea in the morning.","ru":"По привычке она всегда пьёт чай по утрам.","vi":"Theo thói quen, cô luôn uống trà vào buổi sáng.","fa":"از روی عادت، همیشه صبح ها چای می نوشد."}]},{"word":"die Gewohnheit ablegen","en":"to break a habit","ru":"избавиться от привычки, отказаться от привычки","vi":"phá vỡ thói quen","fa":"عادت را ترک کن","examples":[{"de":"Es ist schwer, eine schlechte Gewohnheit abzulegen.","en":"It is hard to break a bad habit.","ru":"Трудно избавиться от плохой привычки.","vi":"Thật khó để bỏ một thói quen xấu.","fa":"ترک یک عادت بد سخت است."},{"de":"Sie hat die Gewohnheit abgelegt, jeden Abend fernzusehen.","en":"She has given up the habit of watching television every evening.","ru":"Она избавилась от привычки смотреть телевизор каждый вечер.","vi":"Cô đã từ bỏ thói quen xem tivi mỗi tối.","fa":"او عادت هر شب تماشای تلویزیون را ترک کرده است."},{"de":"Diese Gewohnheit musst du dringend ablegen.","en":"You urgently need to break this habit.","ru":"От этой привычки тебе срочно нужно избавиться.","vi":"Bạn cần khẩn trương bỏ thói quen này.","fa":"شما باید فوراً این عادت را ترک کنید."}]},{"word":"die Gewohnheitsänderung","en":"change of habit","ru":"изменение привычек","vi":"sự thay đổi thói quen","fa":"تغییر عادت","examples":[{"de":"Eine gesunde Ernährung verlangt oft eine Gewohnheitsänderung.","en":"A healthy diet often requires a change of habit.","ru":"Здоровое питание часто требует изменения привычек.","vi":"Một chế độ ăn uống lành mạnh thường đòi hỏi phải thay đổi thói quen.","fa":"یک رژیم غذایی سالم اغلب نیاز به تغییر عادات دارد."},{"de":"Die Gewohnheitsänderung fiel ihm am Anfang sehr schwer.","en":"The change of habit was very hard for him at first.","ru":"Изменение привычек поначалу давалось ему очень тяжело.","vi":"Ban đầu, việc thay đổi thói quen của anh ấy rất khó khăn đối với anh ấy.","fa":"تغییر عادات در ابتدا برای او بسیار سخت بود."},{"de":"Schon eine kleine Gewohnheitsänderung kann viel bewirken.","en":"Even a small change of habit can make a big difference.","ru":"Даже небольшое изменение привычки может многое изменить.","vi":"Ngay cả một thay đổi nhỏ trong thói quen cũng có thể tạo ra sự khác biệt lớn.","fa":"حتی یک تغییر کوچک در عادات می تواند تفاوت بزرگی ایجاد کند."}]},{"word":"die Gewohnheitssache","en":"a matter of habit","ru":"дело привычки","vi":"chuyện của thói quen","fa":"چیز عادت","examples":[{"de":"Früh aufzustehen ist reine Gewohnheitssache.","en":"Getting up early is purely a matter of habit.","ru":"Рано вставать — это чисто дело привычки.","vi":"Dậy sớm chỉ là vấn đề của thói quen.","fa":"زود بیدار شدن فقط یک عادت است."},{"de":"Ob man morgens Kaffee oder Tee trinkt, ist Gewohnheitssache.","en":"Whether you drink coffee or tea in the morning is a matter of habit.","ru":"Пить утром кофе или чай — дело привычки.","vi":"Việc bạn uống cà phê hay trà vào buổi sáng là vấn đề của thói quen.","fa":"اینکه صبح ها قهوه بنوشید یا چای، یک عادت است."},{"de":"Pünktlichkeit ist bei ihm eine Gewohnheitssache.","en":"Punctuality is a matter of habit for him.","ru":"Пунктуальность у него — дело привычки.","vi":"Đúng giờ đối với anh là thói quen.","fa":"وقت شناسی برای او یک عادت است."}]},{"word":"gewöhnlich","en":"usual, ordinary; usually","ru":"обычный, привычный; обычно","vi":"thông thường","fa":"معمولی","examples":[{"de":"Gewöhnlich stehe ich um sieben Uhr auf.","en":"I usually get up at seven o'clock.","ru":"Обычно я встаю в семь часов.","vi":"Tôi thường thức dậy lúc bảy giờ.","fa":"من معمولا ساعت هفت بیدار می شوم."},{"de":"Es war ein ganz gewöhnlicher Tag im Büro.","en":"It was a completely ordinary day at the office.","ru":"Это был совершенно обычный день в офисе.","vi":"Đó là một ngày bình thường ở văn phòng.","fa":"یک روز معمولی در دفتر بود."},{"de":"Wie gewöhnlich kochte sie am Sonntag für alle.","en":"As usual, she cooked for everyone on Sunday.","ru":"Как обычно, в воскресенье она готовила для всех.","vi":"Như thường lệ, cô ấy nấu ăn cho mọi người vào ngày chủ nhật.","fa":"طبق معمول یکشنبه برای همه آشپزی کرد."}]},{"word":"gewohnt","en":"accustomed to, used to (something one is familiar with)","ru":"привычный (то, к чему привык)","vi":"thông thường","fa":"معمولی","examples":[{"de":"Ich bin es gewohnt, früh aufzustehen.","en":"I am used to getting up early.","ru":"Я привык рано вставать.","vi":"Tôi đã quen với việc dậy sớm.","fa":"من به زود بیدار شدن عادت دارم"},{"de":"Sie arbeitet wie gewohnt sehr sorgfältig.","en":"She works very carefully, as usual.","ru":"Она работает очень тщательно, как всегда.","vi":"Như thường lệ, cô ấy làm việc rất cẩn thận.","fa":"طبق معمول، او با دقت کار می کند."},{"de":"Wir sind harte Arbeit gewohnt.","en":"We are used to hard work.","ru":"Мы привыкли к тяжёлой работе.","vi":"Chúng ta đã quen làm việc chăm chỉ.","fa":"ما به کار سخت عادت کرده ایم."}]},{"word":"gewöhnt","en":"used to (something one has grown accustomed to, with 'an')","ru":"привыкший (к чему-либо, с предлогом «an»)","vi":"đã từng","fa":"استفاده می شود","examples":[{"de":"Ich habe mich an das neue Klima gewöhnt.","en":"I have got used to the new climate.","ru":"Я привык к новому климату.","vi":"Tôi đã quen với khí hậu mới.","fa":"من به آب و هوای جدید عادت کرده ام."},{"de":"Sie ist an viel Stress gewöhnt.","en":"She is used to a lot of stress.","ru":"Она привыкла к большому стрессу.","vi":"Cô ấy đã quen với rất nhiều căng thẳng.","fa":"او به استرس زیاد عادت کرده است."},{"de":"An die Kälte habe ich mich noch nicht gewöhnt.","en":"I have not yet got used to the cold.","ru":"Я ещё не привык к холоду.","vi":"Tôi vẫn chưa quen với cái lạnh.","fa":"هنوز به سرما عادت نکردم."}]},{"word":"das Gewürz","en":"spice","ru":"специя, приправа","vi":"gia vị","fa":"ادویه","examples":[{"de":"In diesem Gericht sind viele Gewürze enthalten.","en":"This dish contains many spices.","ru":"В этом блюде много специй.","vi":"Có rất nhiều gia vị trong món ăn này.","fa":"ادویه های زیادی در این غذا وجود دارد."},{"de":"Pfeffer und Salz sind die häufigsten Gewürze.","en":"Pepper and salt are the most common spices.","ru":"Перец и соль — самые распространённые специи.","vi":"Hạt tiêu và muối là những loại gia vị phổ biến nhất.","fa":"فلفل و نمک رایج ترین ادویه جات هستند."}]},{"word":"die Gewürzmischung","en":"spice blend","ru":"смесь специй (пряностей)","vi":"hỗn hợp gia vị","fa":"مخلوط ادویه","examples":[{"de":"Diese Gewürzmischung passt gut zu Fleisch.","en":"This spice blend goes well with meat.","ru":"Эта смесь специй хорошо подходит к мясу.","vi":"Hỗn hợp gia vị này rất hợp với thịt.","fa":"این ترکیب ادویه به خوبی با گوشت سازگار است."},{"de":"Sie hat eine eigene Gewürzmischung entwickelt.","en":"She developed her own spice blend.","ru":"Она разработала собственную смесь специй.","vi":"Cô đã phát triển hỗn hợp gia vị của riêng mình.","fa":"او مخلوط ادویه خود را ساخته است."},{"de":"Die Gewürzmischung gibt dem Eintopf ein besonderes Aroma.","en":"The spice blend gives the stew a special aroma.","ru":"Смесь специй придаёт рагу особый аромат.","vi":"Hỗn hợp gia vị mang lại cho món hầm một mùi thơm đặc biệt.","fa":"مخلوط ادویه عطر خاصی به خورش می دهد."}]},{"word":"gießen","en":"to water (plants); to pour","ru":"поливать; лить","vi":"đổ","fa":"ریختن","examples":[{"de":"Kannst du bitte die Blumen gießen?","en":"Can you please water the flowers?","ru":"Можешь полить цветы, пожалуйста?","vi":"Bạn có thể vui lòng tưới hoa được không?","fa":"میشه لطفا به گلها آب بدهید؟"},{"de":"Sie gießt vorsichtig Wasser in die Vase.","en":"She carefully pours water into the vase.","ru":"Она осторожно наливает воду в вазу.","vi":"Cô cẩn thận đổ nước vào bình.","fa":"او با احتیاط آب را داخل گلدان می ریزد."}]},{"word":"das Gift","en":"poison","ru":"яд","vi":"chất độc","fa":"سم","examples":[{"de":"Manche Pflanzen enthalten gefährliches Gift.","en":"Some plants contain dangerous poison.","ru":"Некоторые растения содержат опасный яд.","vi":"Một số cây có chứa chất độc nguy hiểm.","fa":"برخی از گیاهان حاوی سم خطرناک هستند."},{"de":"Die Schlange tötet ihre Beute mit Gift.","en":"The snake kills its prey with poison.","ru":"Змея убивает свою добычу ядом.","vi":"Con rắn giết chết con mồi bằng chất độc.","fa":"مار طعمه خود را با سم می کشد."}]},{"word":"giftig","en":"poisonous, toxic","ru":"ядовитый, токсичный","vi":"chất độc","fa":"سمی","examples":[{"de":"Diese Pilze sind giftig und darf man nicht essen.","en":"These mushrooms are poisonous and must not be eaten.","ru":"Эти грибы ядовиты, их нельзя есть.","vi":"Những loại nấm này có độc và không nên ăn.","fa":"این قارچ ها سمی هستند و نباید مصرف شوند."},{"de":"Vorsicht, diese Pflanze ist sehr giftig.","en":"Careful, this plant is very poisonous.","ru":"Осторожно, это растение очень ядовито.","vi":"Hãy cẩn thận, cây này rất độc.","fa":"مراقب باشید این گیاه بسیار سمی است."},{"de":"Die Schlange ist giftig, geh nicht zu nah heran.","en":"The snake is venomous, do not get too close.","ru":"Змея ядовита, не подходи слишком близко.","vi":"Rắn có độc, đừng đến gần.","fa":"مار سمی است، زیاد نزدیک نشوید."}]},{"word":"das Girokonto","en":"current account, checking account","ru":"текущий (расчётный) счёт","vi":"tài khoản séc","fa":"the checking account","examples":[{"de":"Ich möchte ein Girokonto eröffnen.","en":"I would like to open a current account.","ru":"Я хотел бы открыть текущий счёт.","vi":"Tôi muốn mở một tài khoản séc.","fa":"من می خواهم یک حساب جاری باز کنم."},{"de":"Mein Gehalt geht jeden Monat auf mein Girokonto.","en":"My salary goes into my current account every month.","ru":"Моя зарплата каждый месяц поступает на мой текущий счёт.","vi":"Tiền lương của tôi được chuyển vào tài khoản séc của tôi hàng tháng.","fa":"حقوق من هر ماه به حساب جاری من می رود."},{"de":"Das Girokonto ist bei dieser Bank kostenlos.","en":"The current account is free at this bank.","ru":"Текущий счёт в этом банке бесплатный.","vi":"Tài khoản séc là miễn phí tại ngân hàng này.","fa":"حساب جاری در این بانک رایگان است."}]},{"word":"die Gitarre","en":"guitar","ru":"гитара","vi":"cây đàn guitar","fa":"گیتار","examples":[{"de":"Er spielt seit zehn Jahren Gitarre.","en":"He has been playing the guitar for ten years.","ru":"Он играет на гитаре уже десять лет.","vi":"Anh ấy đã chơi guitar được mười năm.","fa":"ده سال است که گیتار می نوازد."},{"de":"Sie hat sich eine neue Gitarre gekauft.","en":"She bought herself a new guitar.","ru":"Она купила себе новую гитару.","vi":"Cô ấy đã mua một cây đàn guitar mới.","fa":"او یک گیتار جدید خرید."}]},{"word":"das Glacé","en":"ice cream (Swiss); glacé / icing","ru":"мороженое (швейц.); глазурь, помадка","vi":"kem","fa":"بستنی","examples":[{"de":"An heißen Tagen kaufen wir uns ein Glacé.","en":"On hot days we buy ourselves an ice cream.","ru":"В жаркие дни мы покупаем себе мороженое.","vi":"Vào những ngày nắng nóng chúng tôi mua kem.","fa":"در روزهای گرم بستنی می خریم."},{"de":"Das Kind wollte unbedingt ein Glacé am Stiel.","en":"The child really wanted an ice lolly.","ru":"Ребёнок непременно хотел мороженое на палочке.","vi":"Đứa trẻ thực sự muốn ăn kem trên que.","fa":"بچه خیلی دلم یک بستنی روی چوب می خواست."},{"de":"Der Kuchen war mit einem süßen Glacé überzogen.","en":"The cake was covered with a sweet glacé icing.","ru":"Торт был покрыт сладкой глазурью.","vi":"Chiếc bánh được phủ một lớp kem ngọt ngào.","fa":"روی کیک با بستنی شیرین پوشیده شده بود."}]},{"word":"die Glace","en":"ice cream (Swiss German)","ru":"мороженое (швейц. вариант нем.)","vi":"kem","fa":"بستنی","examples":[{"de":"Im Sommer essen wir oft eine Glace am See.","en":"In summer we often eat an ice cream by the lake.","ru":"Летом мы часто едим мороженое у озера.","vi":"Vào mùa hè chúng tôi thường ăn kem bên hồ.","fa":"در تابستان اغلب در کنار دریاچه بستنی می خوریم."},{"de":"Welche Glace möchtest du, Schokolade oder Vanille?","en":"Which ice cream would you like, chocolate or vanilla?","ru":"Какое мороженое ты хочешь, шоколадное или ванильное?","vi":"Bạn muốn loại kem nào, sô cô la hay vani?","fa":"کدام بستنی را دوست دارید، شکلاتی یا وانیلی؟"},{"de":"Die Kinder freuen sich auf eine kalte Glace.","en":"The children are looking forward to a cold ice cream.","ru":"Дети радуются холодному мороженому.","vi":"Bọn trẻ háo hức được ăn kem lạnh.","fa":"بچه ها منتظر بستنی سرد هستند."}]},{"word":"glatt","en":"smooth; slippery","ru":"гладкий; скользкий","vi":"mịn màng","fa":"صاف","examples":[{"de":"Die Straße ist bei Regen sehr glatt.","en":"The road is very slippery when it rains.","ru":"Дорога очень скользкая, когда идёт дождь.","vi":"Đường rất trơn khi trời mưa.","fa":"جاده هنگام بارندگی بسیار لغزنده است."},{"de":"Der Tisch hat eine glatte Oberfläche.","en":"The table has a smooth surface.","ru":"У стола гладкая поверхность.","vi":"Bàn có bề mặt nhẵn.","fa":"میز دارای سطح صاف است."}]},{"word":"glauben","en":"to believe, to think","ru":"верить, думать","vi":"tin tưởng","fa":"باور کنید","examples":[{"de":"Ich glaube, es wird morgen regnen.","en":"I think it will rain tomorrow.","ru":"Я думаю, завтра пойдёт дождь.","vi":"Tôi nghĩ ngày mai trời sẽ mưa.","fa":"فکر کنم فردا بارون بیاد"},{"de":"Sie glaubt fest an Gott.","en":"She firmly believes in God.","ru":"Она твёрдо верит в Бога.","vi":"Cô tin tưởng chắc chắn vào Chúa.","fa":"او به خدا اعتقاد راسخ دارد."}]},{"word":"gleich","en":"same, equal; immediately, right away","ru":"одинаковый, равный; сейчас же","vi":"giống nhau","fa":"همان","examples":[{"de":"Beide Kinder sind gleich groß.","en":"Both children are the same height.","ru":"Оба ребёнка одного роста.","vi":"Cả hai đứa trẻ đều có cùng kích thước.","fa":"هر دو بچه یک اندازه هستند."},{"de":"Ich komme gleich zu dir.","en":"I'll come to you right away.","ru":"Я сейчас же приду к тебе.","vi":"Tôi sẽ đến với bạn sớm.","fa":"به زودی میام پیشت"}]},{"word":"gleichberechtigt","en":"having equal rights, equal","ru":"равноправный, имеющий равные права","vi":"bằng nhau","fa":"برابر","examples":[{"de":"Männer und Frauen sollten gleichberechtigt sein.","en":"Men and women should have equal rights.","ru":"Мужчины и женщины должны иметь равные права.","vi":"Nam giới và phụ nữ phải có quyền bình đẳng.","fa":"زن و مرد باید از حقوق مساوی برخوردار باشند."},{"de":"In dieser Firma sind alle Mitarbeiter gleichberechtigt.","en":"In this company all employees are equal.","ru":"В этой фирме все сотрудники равноправны.","vi":"Ở công ty này mọi nhân viên đều có quyền bình đẳng.","fa":"در این شرکت همه کارکنان از حقوق مساوی برخوردارند."},{"de":"Wir streben eine gleichberechtigte Gesellschaft an.","en":"We strive for a society with equal rights.","ru":"Мы стремимся к обществу равных прав.","vi":"Chúng tôi phấn đấu vì một xã hội bình đẳng.","fa":"ما برای یک جامعه برابر تلاش می کنیم."}]},{"word":"die Gleichberechtigung","en":"equality; equal rights","ru":"равноправие, равенство прав","vi":"sự bình đẳng","fa":"برابری","examples":[{"de":"Gleichberechtigung von Mann und Frau ist im Gesetz verankert.","en":"Equal rights for men and women are anchored in the law.","ru":"Равноправие мужчин и женщин закреплено в законе.","vi":"Sự bình đẳng giữa nam và nữ được ghi trong luật.","fa":"برابری زن و مرد در قانون لنگر انداخته است."},{"de":"Viele kämpfen seit Jahren für mehr Gleichberechtigung.","en":"Many have been fighting for more equality for years.","ru":"Многие годами борются за большее равноправие.","vi":"Nhiều người đã đấu tranh để có được sự bình đẳng hơn trong nhiều năm.","fa":"بسیاری سال هاست که برای برابری بیشتر می جنگند."},{"de":"Echte Gleichberechtigung gibt es noch nicht überall.","en":"Real equality does not yet exist everywhere.","ru":"Настоящего равноправия ещё не везде достигли.","vi":"Sự bình đẳng thực sự chưa tồn tại ở mọi nơi.","fa":"برابری واقعی هنوز در همه جا وجود ندارد."}]},{"word":"gleichfalls","en":"likewise; the same to you","ru":"также, взаимно; и вам того же","vi":"tương tự như vậy","fa":"به همین ترتیب","examples":[{"de":"„Schönen Feierabend!“ – „Danke, gleichfalls!“","en":"\"Have a nice evening!\" - \"Thanks, likewise!\"","ru":"«Хорошего вечера!» — «Спасибо, и вам того же!»","vi":"“Chúc một buổi tối vui vẻ!” - \"Cảm ơn bạn cũng vậy!\"","fa":"\"عصر خوبی داشته باشید!\" - \"به همین ترتیب از شما متشکرم!\""},{"de":"Ich wünsche dir ein schönes Wochenende. – Gleichfalls!","en":"I wish you a nice weekend. - The same to you!","ru":"Желаю тебе хороших выходных. — И тебе того же!","vi":"Tôi chúc bạn một ngày cuối tuần vui vẻ. - Anh cũng thế!","fa":"آخر هفته خوبی براتون آرزو میکنم - تو هم همینطور!"},{"de":"Er grüßte freundlich und sie nickte gleichfalls.","en":"He greeted her warmly and she nodded likewise.","ru":"Он тепло её поприветствовал, и она в ответ кивнула.","vi":"Anh chào hỏi thân thiện và cô gật đầu đáp lại.","fa":"او دوستانه احوالپرسی کرد و او در جواب سرش را تکان داد."}]},{"word":"das Gleichgewichtsgefühl","en":"sense of balance","ru":"чувство равновесия","vi":"cảm giác cân bằng","fa":"احساس تعادل","examples":[{"de":"Die Baumhaltung trainiert das Gleichgewichtsgefühl.","en":"The tree pose trains your sense of balance.","ru":"Поза дерева тренирует чувство равновесия.","vi":"Tư thế cái cây rèn luyện cảm giác cân bằng của bạn.","fa":"ژست درختی حس تعادل شما را آموزش می دهد."},{"de":"Mit geschlossenen Augen wird mein Gleichgewichtsgefühl getestet.","en":"With my eyes closed my sense of balance is tested.","ru":"С закрытыми глазами моё чувство равновесия проверяется.","vi":"Cảm giác cân bằng của tôi được kiểm tra khi tôi nhắm mắt.","fa":"حس تعادل من با چشمان بسته آزمایش می شود."},{"de":"Ein gutes Gleichgewichtsgefühl hilft auch im Alltag.","en":"A good sense of balance helps in everyday life too.","ru":"Хорошее чувство равновесия помогает и в повседневной жизни.","vi":"Cảm giác cân bằng tốt cũng giúp ích trong cuộc sống hàng ngày.","fa":"حس خوب تعادل در زندگی روزمره نیز کمک می کند."}]},{"word":"der Gleichgewichtssinn","en":"sense of balance","ru":"чувство равновесия","vi":"cảm giác cân bằng","fa":"حس تعادل","examples":[{"de":"Yoga auf einem Bein trainiert den Gleichgewichtssinn.","en":"Yoga on one leg trains the sense of balance.","ru":"Йога на одной ноге тренирует чувство равновесия.","vi":"Yoga trên một chân rèn luyện cảm giác thăng bằng.","fa":"یوگا روی یک پا حس تعادل را آموزش می دهد."},{"de":"Mit der Zeit wird dein Gleichgewichtssinn besser.","en":"Over time your sense of balance improves.","ru":"Со временем твоё чувство равновесия улучшается.","vi":"Theo thời gian, cảm giác cân bằng của bạn sẽ được cải thiện.","fa":"با گذشت زمان، حس تعادل شما بهبود می یابد."},{"de":"Diese Haltung verlangt einen guten Gleichgewichtssinn.","en":"This posture demands a good sense of balance.","ru":"Эта поза требует хорошего чувства равновесия.","vi":"Tư thế này đòi hỏi khả năng giữ thăng bằng tốt.","fa":"این وضعیت نیاز به یک حس خوب تعادل دارد."}]},{"word":"gleichzeitig","en":"at the same time; simultaneous","ru":"одновременно; одновременный","vi":"cùng lúc","fa":"در همان زمان","examples":[{"de":"Man kann nicht zwei Dinge gleichzeitig richtig machen.","en":"You can't do two things properly at the same time.","ru":"Нельзя делать два дела как следует одновременно.","vi":"Bạn không thể làm đúng hai việc cùng một lúc.","fa":"شما نمی توانید دو کار را همزمان انجام دهید."},{"de":"Die beiden kamen gleichzeitig am Ziel an.","en":"The two arrived at the finish at the same time.","ru":"Оба пришли к финишу одновременно.","vi":"Hai người đến đích cùng một lúc.","fa":"آن دو همزمان به مقصد رسیدند."}]},{"word":"das Gleis","en":"railway track, platform","ru":"путь, платформа (ж/д)","vi":"đường đua","fa":"مسیر","examples":[{"de":"Der Zug nach Berlin fährt von Gleis 5 ab.","en":"The train to Berlin departs from platform 5.","ru":"Поезд в Берлин отправляется с пути 5.","vi":"Tàu tới Berlin khởi hành từ sân ga số 5.","fa":"قطار به برلین از سکوی 5 حرکت می کند."},{"de":"Bitte bleiben Sie hinter der Linie am Gleis.","en":"Please stay behind the line on the platform.","ru":"Пожалуйста, оставайтесь за линией на платформе.","vi":"Hãy ở phía sau vạch trên đường đua.","fa":"لطفا پشت خط در مسیر بمانید."}]},{"word":"der Gletscher","en":"glacier","ru":"ледник","vi":"sông băng","fa":"the glacier","examples":[{"de":"Der Gletscher zieht sich Jahr für Jahr weiter zurück.","en":"The glacier is retreating further year after year.","ru":"Ледник год за годом отступает всё дальше.","vi":"Sông băng tiếp tục rút lui năm này qua năm khác.","fa":"این یخچال سال به سال به عقب نشینی خود ادامه می دهد."},{"de":"Vom Gipfel aus sieht man den riesigen Gletscher im Tal.","en":"From the summit you can see the huge glacier in the valley.","ru":"С вершины виден огромный ледник в долине.","vi":"Từ đỉnh núi bạn có thể nhìn thấy sông băng khổng lồ trong thung lũng.","fa":"از قله می توانید یخچال عظیم در دره را ببینید."},{"de":"Der Gletscher ist in fünfzig Jahren um Hunderte Meter geschrumpft.","en":"The glacier has shrunk by hundreds of metres in fifty years.","ru":"За пятьдесят лет ледник сократился на сотни метров.","vi":"Sông băng đã bị thu hẹp hàng trăm mét trong 50 năm.","fa":"این یخچال طی پنجاه سال صدها متر کوچک شده است."}]},{"word":"das Glück","en":"luck, happiness","ru":"удача, счастье","vi":"hạnh phúc","fa":"شادی","examples":[{"de":"Wir hatten Glück, dass es nicht geregnet hat.","en":"We were lucky that it didn't rain.","ru":"Нам повезло, что не было дождя.","vi":"Chúng tôi thật may mắn vì trời không mưa.","fa":"خوش شانس بودیم که باران نیامد."},{"de":"Ich wünsche dir viel Glück für die Prüfung.","en":"I wish you good luck for the exam.","ru":"Желаю тебе удачи на экзамене.","vi":"Tôi chúc bạn may mắn cho kỳ thi.","fa":"برای شما آرزوی موفقیت در امتحان دارم."}]},{"word":"glücklich","en":"happy","ru":"счастливый","vi":"hạnh phúc","fa":"خوشحال","examples":[{"de":"Seit der Hochzeit ist sie sehr glücklich.","en":"She has been very happy since the wedding.","ru":"После свадьбы она очень счастлива.","vi":"Cô ấy đã rất hạnh phúc kể từ khi kết hôn.","fa":"او از زمان عروسی بسیار خوشحال است."},{"de":"Ich bin glücklich, dass du gekommen bist.","en":"I'm happy that you came.","ru":"Я рад, что ты пришёл.","vi":"Tôi rất vui vì bạn đã đến.","fa":"خوشحالم که اومدی"},{"de":"Die Kinder sahen glücklich und zufrieden aus.","en":"The children looked happy and content.","ru":"Дети выглядели счастливыми и довольными.","vi":"Bọn trẻ trông có vẻ vui vẻ và hài lòng.","fa":"بچه ها خوشحال و راضی به نظر می رسیدند."}]},{"word":"der Glühwein","en":"mulled wine","ru":"глинтвейн","vi":"rượu ngâm","fa":"شراب مولد","examples":[{"de":"Im Advent trinken viele Leute gern Glühwein.","en":"During Advent many people like to drink mulled wine.","ru":"В предрождественское время многие любят пить глинтвейн.","vi":"Nhiều người thích uống rượu ngâm trong Mùa Vọng.","fa":"بسیاری از مردم دوست دارند در طول ظهور شراب مولد بنوشند."},{"de":"Der Glühwein wird mit Gewürzen heiß gemacht.","en":"The mulled wine is heated up with spices.","ru":"Глинтвейн подогревают со специями.","vi":"Rượu ngâm được làm nóng với gia vị.","fa":"شراب مولد گرم با ادویه درست می شود."},{"de":"Ein Becher Glühwein kostet auf dem Markt drei Euro.","en":"A mug of mulled wine costs three euros at the market.","ru":"Кружка глинтвейна стоит на рынке три евро.","vi":"Một cốc rượu ngâm có giá 3 euro ở chợ.","fa":"یک فنجان شراب مولد در بازار سه یورو قیمت دارد."}]},{"word":"das Gold","en":"gold","ru":"золото","vi":"vàng","fa":"طلا","examples":[{"de":"Der Ring ist aus reinem Gold.","en":"The ring is made of pure gold.","ru":"Кольцо сделано из чистого золота.","vi":"Chiếc nhẫn được làm bằng vàng nguyên chất.","fa":"انگشتر از طلای خالص ساخته شده است."},{"de":"Sie hat bei den Olympischen Spielen Gold gewonnen.","en":"She won gold at the Olympic Games.","ru":"Она выиграла золото на Олимпийских играх.","vi":"Cô đã giành huy chương vàng tại Thế vận hội.","fa":"او در المپیک طلا گرفت."}]},{"word":"Golf","en":"golf (the sport)","ru":"гольф","vi":"chơi gôn","fa":"گلف","examples":[{"de":"Mein Vater spielt jeden Samstag Golf.","en":"My father plays golf every Saturday.","ru":"Мой отец играет в гольф каждую субботу.","vi":"Bố tôi chơi gôn vào thứ Bảy hàng tuần.","fa":"پدرم هر شنبه گلف بازی می کند."},{"de":"Wir haben im Urlaub einen Golfplatz besucht.","en":"We visited a golf course on vacation.","ru":"В отпуске мы посетили поле для гольфа.","vi":"Chúng tôi đã đến thăm một sân gôn vào kỳ nghỉ.","fa":"ما در تعطیلات از یک زمین گلف بازدید کردیم."}]},{"word":"der Gott","en":"God","ru":"Бог","vi":"vị thần","fa":"خدا","examples":[{"de":"Viele Menschen glauben an einen Gott.","en":"Many people believe in a God.","ru":"Многие люди верят в Бога.","vi":"Nhiều người tin vào một Thiên Chúa.","fa":"بسیاری از مردم به خدای واحد ایمان دارند."},{"de":"In der Kirche beten die Menschen zu Gott.","en":"In church, people pray to God.","ru":"В церкви люди молятся Богу.","vi":"Trong nhà thờ mọi người cầu nguyện với Chúa.","fa":"در کلیسا مردم به خدا دعا می کنند."}]},{"word":"die Grafik","en":"graphic; chart","ru":"график, графика","vi":"đồ họa","fa":"گرافیک","examples":[{"de":"Die Grafik zeigt die Entwicklung der Preise.","en":"The chart shows the development of prices.","ru":"График показывает изменение цен.","vi":"Đồ họa cho thấy sự phát triển của giá cả.","fa":"نمودار توسعه قیمت ها را نشان می دهد."},{"de":"Der Designer hat eine neue Grafik für die Webseite erstellt.","en":"The designer created a new graphic for the website.","ru":"Дизайнер создал новую графику для сайта.","vi":"Nhà thiết kế đã tạo ra một đồ họa mới cho trang web.","fa":"طراح یک گرافیک جدید برای وب سایت ایجاد کرد."}]},{"word":"die Graphik","en":"graphic, chart, graphics","ru":"график, диаграмма, графика","vi":"đồ họa","fa":"گرافیک","examples":[{"de":"Die Graphik zeigt die Entwicklung der Preise.","en":"The chart shows the development of prices.","ru":"График показывает динамику цен.","vi":"Biểu đồ cho thấy sự phát triển của giá cả.","fa":"نمودار توسعه قیمت ها را نشان می دهد."},{"de":"Er erstellte eine Graphik für seine Präsentation.","en":"He created a graphic for his presentation.","ru":"Он создал график для своей презентации.","vi":"Anh ấy đã tạo ra một đồ họa cho bài thuyết trình của mình.","fa":"او یک گرافیک برای ارائه خود ایجاد کرد."},{"de":"Diese Graphik ist leicht zu verstehen.","en":"This chart is easy to understand.","ru":"Этот график легко понять.","vi":"Đồ họa này rất dễ hiểu.","fa":"این گرافیک به راحتی قابل درک است."}]},{"word":"das Gras","en":"grass","ru":"трава","vi":"cỏ","fa":"چمن","examples":[{"de":"Die Kinder spielen barfuß im Gras.","en":"The children are playing barefoot in the grass.","ru":"Дети играют босиком на траве.","vi":"Những đứa trẻ chơi chân trần trên bãi cỏ.","fa":"بچه ها با پای برهنه در چمن بازی می کنند."},{"de":"Im Sommer muss man das Gras oft mähen.","en":"In summer you have to mow the grass often.","ru":"Летом траву нужно часто косить.","vi":"Vào mùa hè bạn phải cắt cỏ thường xuyên.","fa":"در تابستان باید اغلب چمن ها را درو کنید."}]},{"word":"gratis","en":"free of charge","ru":"бесплатно","vi":"miễn phí","fa":"رایگان","examples":[{"de":"Der Eintritt ins Museum ist heute gratis.","en":"Admission to the museum is free today.","ru":"Вход в музей сегодня бесплатный.","vi":"Vào cửa bảo tàng ngày hôm nay là miễn phí.","fa":"ورود به موزه امروز رایگان است."},{"de":"Kinder unter sechs Jahren fahren gratis mit dem Bus.","en":"Children under six ride the bus for free.","ru":"Дети до шести лет ездят на автобусе бесплатно.","vi":"Trẻ em dưới sáu tuổi được đi miễn phí trên xe buýt.","fa":"سفر کودکان زیر شش سال با اتوبوس رایگان است."}]},{"word":"die Gratulation","en":"congratulation","ru":"поздравление","vi":"lời chúc mừng","fa":"تبریک","examples":[{"de":"Herzliche Gratulation zu deinem neuen Job!","en":"Warm congratulations on your new job!","ru":"Сердечные поздравления с новой работой!","vi":"Xin chúc mừng công việc mới của bạn!","fa":"شغل جدیدتان را تبریک می گویم!"},{"de":"Wir haben eine Karte mit unserer Gratulation geschickt.","en":"We sent a card with our congratulations.","ru":"Мы отправили открытку с нашими поздравлениями.","vi":"Chúng tôi đã gửi một tấm thiệp với lời chúc mừng của chúng tôi.","fa":"ما یک کارت با تبریک خود فرستادیم."}]},{"word":"gratulieren","en":"to congratulate","ru":"поздравлять","vi":"chúc mừng","fa":"تبریک گفتن","examples":[{"de":"Ich möchte dir zum Geburtstag gratulieren.","en":"I would like to congratulate you on your birthday.","ru":"Я хочу поздравить тебя с днём рождения.","vi":"Tôi muốn chúc bạn sinh nhật vui vẻ.","fa":"می خواهم تولدت را تبریک بگویم."},{"de":"Alle Kollegen haben ihr zur bestandenen Prüfung gratuliert.","en":"All the colleagues congratulated her on passing the exam.","ru":"Все коллеги поздравили её со сдачей экзамена.","vi":"Tất cả các đồng nghiệp đều chúc mừng cô đã vượt qua kỳ thi.","fa":"همه همکاران قبولی در امتحان را به او تبریک گفتند."}]},{"word":"greifen","en":"to grab; to reach for","ru":"хватать, браться","vi":"chộp lấy","fa":"چنگ زدن","examples":[{"de":"Das Baby greift nach dem Spielzeug.","en":"The baby reaches for the toy.","ru":"Малыш тянется за игрушкой.","vi":"Bé với tay lấy đồ chơi.","fa":"کودک دستش را به سمت اسباب بازی می برد."},{"de":"Er griff schnell nach seiner Tasche.","en":"He quickly grabbed his bag.","ru":"Он быстро схватил свою сумку.","vi":"Anh nhanh chóng đưa tay lấy túi xách của mình.","fa":"سریع دستش را به سمت کیفش برد."}]},{"word":"die Grenze","en":"border; limit","ru":"граница","vi":"biên giới","fa":"مرز","examples":[{"de":"Wir haben die Grenze zwischen Deutschland und Österreich überquert.","en":"We crossed the border between Germany and Austria.","ru":"Мы пересекли границу между Германией и Австрией.","vi":"Chúng tôi vượt qua biên giới giữa Đức và Áo.","fa":"از مرز آلمان و اتریش گذشتیم."},{"de":"Jeder Mensch hat seine eigenen Grenzen.","en":"Every person has their own limits.","ru":"У каждого человека есть свои границы.","vi":"Mỗi người đều có những giới hạn riêng của mình.","fa":"هر فردی محدودیت های خاص خود را دارد."}]},{"word":"der Grill","en":"grill, barbecue","ru":"гриль, барбекю, мангал","vi":"lò nướng","fa":"گریل","examples":[{"de":"Im Sommer machen wir oft Würstchen auf dem Grill.","en":"In summer we often make sausages on the barbecue.","ru":"Летом мы часто готовим сосиски на гриле.","vi":"Vào mùa hè chúng ta thường làm xúc xích nướng.","fa":"در تابستان اغلب سوسیس روی کباب درست می کنیم."},{"de":"Der Grill muss erst richtig heiß werden.","en":"The grill has to get properly hot first.","ru":"Гриль сначала должен как следует нагреться.","vi":"Đầu tiên vỉ nướng phải thật nóng.","fa":"ابتدا باید گریل خیلی داغ شود."},{"de":"Wir haben einen neuen Grill für den Garten gekauft.","en":"We bought a new barbecue for the garden.","ru":"Мы купили новый гриль для сада.","vi":"Chúng tôi đã mua một cái lò nướng mới cho khu vườn.","fa":"ما یک گریل جدید برای باغ خریدیم."}]},{"word":"grillen","en":"to grill; to barbecue","ru":"жарить на гриле","vi":"nướng","fa":"کباب","examples":[{"de":"Am Wochenende grillen wir im Garten.","en":"On the weekend we grill in the garden.","ru":"На выходных мы жарим на гриле в саду.","vi":"Cuối tuần chúng tôi nướng thịt ngoài vườn.","fa":"آخر هفته در باغ کباب می کنیم."},{"de":"Er grillt gern Fleisch und Gemüse.","en":"He likes to grill meat and vegetables.","ru":"Он любит жарить на гриле мясо и овощи.","vi":"Anh ấy thích nướng thịt và rau.","fa":"او دوست دارد گوشت و سبزیجات را کباب کند."}]},{"word":"grillieren","en":"to grill; to barbecue (Swiss German)","ru":"жарить на гриле (швейц.)","vi":"nướng","fa":"کباب","examples":[{"de":"In der Schweiz sagt man oft \"grillieren\" statt \"grillen\".","en":"In Switzerland people often say \"grillieren\" instead of \"grillen\".","ru":"В Швейцарии часто говорят «grillieren» вместо «grillen».","vi":"Ở Thụy Sĩ người ta thường nói \"nướng\" thay vì \"nướng\".","fa":"در سوئیس اغلب به جای \"گریل\" می گویند \"گریل\"."},{"de":"Wir grillieren heute Abend Würste auf dem Balkon.","en":"This evening we're grilling sausages on the balcony.","ru":"Сегодня вечером мы жарим на гриле колбаски на балконе.","vi":"Tối nay chúng tôi sẽ nướng xúc xích ngoài ban công.","fa":"امروز عصر در بالکن سوسیس کباب می کنیم."}]},{"word":"die Grippe","en":"flu","ru":"грипп","vi":"bệnh cúm","fa":"آنفولانزا","examples":[{"de":"Ich habe Fieber, ich glaube, ich habe die Grippe.","en":"I have a fever, I think I have the flu.","ru":"У меня температура, кажется, у меня грипп.","vi":"Tôi bị sốt, tôi nghĩ mình bị cúm.","fa":"من تب دارم فکر کنم آنفولانزا گرفتم."},{"de":"Im Winter lassen sich viele Leute gegen die Grippe impfen.","en":"In winter many people get vaccinated against the flu.","ru":"Зимой многие люди делают прививку от гриппа.","vi":"Vào mùa đông, nhiều người được tiêm phòng cúm.","fa":"در زمستان، بسیاری از مردم علیه آنفولانزا واکسینه می شوند."}]},{"word":"groß","en":"big; large","ru":"большой","vi":"lớn","fa":"بزرگ","examples":[{"de":"Sie wohnen in einem großen Haus.","en":"They live in a big house.","ru":"Они живут в большом доме.","vi":"Họ sống trong một ngôi nhà lớn.","fa":"آنها در یک خانه بزرگ زندگی می کنند."},{"de":"Mein Bruder ist größer als ich.","en":"My brother is taller than me.","ru":"Мой брат выше меня.","vi":"Anh trai tôi cao hơn tôi.","fa":"برادرم از من بلندتر است."}]},{"word":"Groß-","en":"prefix meaning \"large, grand, great\" (e.g. in \"Großstadt\" = big city)","ru":"приставка со значением «большой, старший, главный» (напр. Großstadt — крупный город)","vi":"lớn-","fa":"بزرگ-","examples":[{"de":"Berlin ist eine Großstadt mit vielen Einwohnern.","en":"Berlin is a big city with many inhabitants.","ru":"Берлин — крупный город с большим количеством жителей.","vi":"Berlin là một thành phố lớn với nhiều cư dân.","fa":"برلین شهر بزرگی است که ساکنان زیادی دارد."},{"de":"Meine Großmutter wohnt bei uns in der Nähe.","en":"My grandmother lives near us.","ru":"Моя бабушка живёт рядом с нами.","vi":"Bà tôi sống gần chúng tôi.","fa":"مادربزرگم نزدیک ما زندگی می کند."}]},{"word":"großzügig","en":"generous","ru":"щедрый","vi":"hào phóng","fa":"سخاوتمندانه","examples":[{"de":"Er ist immer sehr großzügig mit seinen Freunden.","en":"He is always very generous with his friends.","ru":"Он всегда очень щедр со своими друзьями.","vi":"Anh ấy luôn rất hào phóng với bạn bè.","fa":"او همیشه با دوستانش بسیار سخاوتمند است."},{"de":"Vielen Dank für das großzügige Geschenk.","en":"Thank you very much for the generous gift.","ru":"Большое спасибо за щедрый подарок.","vi":"Cảm ơn bạn vì món quà hào phóng.","fa":"ممنون از هدیه سخاوتمندانه"}]},{"word":"der Grund","en":"reason","ru":"причина","vi":"lý do","fa":"دلیل","examples":[{"de":"Was ist der Grund für deine Verspätung?","en":"What is the reason for your lateness?","ru":"В чём причина твоего опоздания?","vi":"Lý do cho sự chậm trễ của bạn là gì?","fa":"دلیل تاخیر شما چیست؟"},{"de":"Aus welchem Grund hast du gekündigt?","en":"For what reason did you quit?","ru":"По какой причине ты уволился?","vi":"Vì lý do gì bạn đã bỏ cuộc?","fa":"به چه دلیلی استعفا دادی؟"}]},{"word":"Der Grund dafür ist, dass …","en":"The reason for that is that … (giving a reason)","ru":"Причина в том, что … (причина)","vi":"Lý do cho điều đó là…","fa":"دلیل آن این است که…","examples":[{"de":"Der Grund dafür ist, dass die Mieten steigen.","en":"The reason for that is that rents are rising.","ru":"Причина в том, что аренда дорожает.","vi":"Nguyên nhân là do giá thuê ngày càng tăng.","fa":"دلیل این امر افزایش اجاره بها است."}]},{"word":"gründen","en":"to found; to establish","ru":"основывать","vi":"thành lập","fa":"ایجاد کند","examples":[{"de":"Die beiden Freunde wollen eine eigene Firma gründen.","en":"The two friends want to found their own company.","ru":"Оба друга хотят основать собственную компанию.","vi":"Hai người bạn muốn thành lập công ty riêng.","fa":"این دو دوست می خواهند شرکت خود را راه اندازی کنند."},{"de":"Die Stadt wurde vor über 500 Jahren gegründet.","en":"The city was founded over 500 years ago.","ru":"Город был основан более 500 лет назад.","vi":"Thành phố được thành lập hơn 500 năm trước.","fa":"این شهر بیش از 500 سال پیش تاسیس شد."}]},{"word":"gründlich","en":"thorough","ru":"тщательный","vi":"triệt để","fa":"به طور کامل","examples":[{"de":"Sie hat die Wohnung gründlich geputzt.","en":"She cleaned the apartment thoroughly.","ru":"Она тщательно убрала квартиру.","vi":"Cô dọn dẹp căn hộ thật kỹ lưỡng.","fa":"او آپارتمان را کاملا تمیز کرد."},{"de":"Der Arzt hat mich gründlich untersucht.","en":"The doctor examined me thoroughly.","ru":"Врач тщательно меня осмотрел.","vi":"Bác sĩ đã khám cho tôi rất kỹ.","fa":"دکتر مرا به طور کامل معاینه کرد."}]},{"word":"grundsätzlich","en":"fundamental; in principle; basically","ru":"принципиальный; в принципе; по сути","vi":"về cơ bản","fa":"اساسا","examples":[{"de":"Grundsätzlich bin ich mit deinem Vorschlag einverstanden.","en":"In principle I agree with your proposal.","ru":"В принципе я согласен с твоим предложением.","vi":"Về cơ bản tôi đồng ý với đề xuất của bạn.","fa":"اساسا با پیشنهاد شما موافقم."},{"de":"Es gibt einen grundsätzlichen Unterschied zwischen den beiden Modellen.","en":"There is a fundamental difference between the two models.","ru":"Между двумя моделями есть принципиальное различие.","vi":"Có một sự khác biệt cơ bản giữa hai mô hình.","fa":"تفاوت اساسی بین این دو مدل وجود دارد."},{"de":"Rauchen ist im Gebäude grundsätzlich verboten.","en":"Smoking in the building is fundamentally prohibited.","ru":"Курить в здании категорически запрещено.","vi":"Hút thuốc thường bị cấm trong tòa nhà.","fa":"سیگار کشیدن در ساختمان به طور کلی ممنوع است."}]},{"word":"das Grundstück","en":"plot of land; property","ru":"земельный участок","vi":"tài sản","fa":"ملک","examples":[{"de":"Meine Eltern haben ein Grundstück am See gekauft.","en":"My parents bought a plot of land by the lake.","ru":"Мои родители купили земельный участок у озера.","vi":"Bố mẹ tôi mua bất động sản trên hồ.","fa":"پدر و مادرم روی دریاچه ملک خریدند."},{"de":"Auf dem Grundstück soll ein neues Haus gebaut werden.","en":"A new house is supposed to be built on the property.","ru":"На этом участке планируется построить новый дом.","vi":"Một ngôi nhà mới sẽ được xây dựng trên khu đất này.","fa":"قرار است یک خانه جدید در ملک ساخته شود."}]},{"word":"die Gründung","en":"founding, establishment","ru":"основание, учреждение (города, государства)","vi":"nền tảng","fa":"بنیاد","examples":[{"de":"Die Gründung der Stadt liegt mehr als tausend Jahre zurück.","en":"The founding of the city dates back more than a thousand years.","ru":"Основание города датируется более чем тысячелетием назад.","vi":"Thành phố được thành lập hơn một ngàn năm trước.","fa":"این شهر بیش از هزار سال پیش تأسیس شد."},{"de":"Nach der Gründung des Staates wurde eine Verfassung verabschiedet.","en":"After the founding of the state a constitution was adopted.","ru":"После основания государства была принята конституция.","vi":"Sau khi nhà nước được thành lập, hiến pháp đã được thông qua.","fa":"پس از تأسیس دولت، قانون اساسی به تصویب رسید."},{"de":"Die Gründung der Universität war ein wichtiges Ereignis.","en":"The founding of the university was an important event.","ru":"Основание университета было важным событием.","vi":"Việc thành lập trường đại học là một sự kiện quan trọng.","fa":"تأسیس دانشگاه یک رویداد مهم بود."}]},{"word":"die Gruppe","en":"group","ru":"группа","vi":"nhóm","fa":"گروه","examples":[{"de":"Die Schüler arbeiten heute in kleinen Gruppen.","en":"The students are working in small groups today.","ru":"Сегодня ученики работают в маленьких группах.","vi":"Hôm nay học sinh làm việc theo nhóm nhỏ.","fa":"امروزه دانش آموزان در گروه های کوچک کار می کنند."},{"de":"Eine Gruppe von Touristen besichtigt das Schloss.","en":"A group of tourists is visiting the castle.","ru":"Группа туристов осматривает замок.","vi":"Một nhóm du khách tham quan lâu đài.","fa":"گروهی از گردشگران از قلعه بازدید می کنند."}]},{"word":"die Gruppenarbeit","en":"group work","ru":"работа в группе (групповое задание)","vi":"làm việc nhóm","fa":"کار گروهی","examples":[{"de":"Im Unterricht machen wir oft Gruppenarbeit.","en":"In class we often do group work.","ru":"На уроке мы часто делаем групповые задания.","vi":"Chúng tôi thường làm việc nhóm trong lớp.","fa":"ما اغلب در کلاس کار گروهی انجام می دهیم."},{"de":"Bei der Gruppenarbeit lernt man, im Team zu arbeiten.","en":"In group work you learn to work as a team.","ru":"В групповой работе учишься работать в команде.","vi":"Trong làm việc nhóm, bạn học cách làm việc theo nhóm.","fa":"در کار گروهی کار گروهی را یاد می گیرید."},{"de":"Die Lehrerin teilte die Klasse für die Gruppenarbeit ein.","en":"The teacher divided the class up for the group work.","ru":"Учительница разделила класс для групповой работы.","vi":"Giáo viên chia lớp để làm việc nhóm.","fa":"معلم کلاس را برای کار گروهی تقسیم کرد."}]},{"word":"grüßen","en":"to greet","ru":"приветствовать, здороваться","vi":"chào","fa":"سلام کردن","examples":[{"de":"Er grüßt jeden Morgen seine Nachbarn.","en":"He greets his neighbors every morning.","ru":"Он приветствует своих соседей каждое утро.","vi":"Anh ấy chào hàng xóm vào mỗi buổi sáng.","fa":"او هر روز صبح به همسایه هایش سلام می کند."},{"de":"Grüß deine Familie von mir!","en":"Say hello to your family for me!","ru":"Передай привет своей семье от меня!","vi":"Gửi lời chào gia đình bạn giùm tôi nhé!","fa":"برای من به خانواده خود سلام برسان!"}]},{"word":"gucken","en":"to look (colloquial)","ru":"смотреть, глядеть","vi":"Nhìn","fa":"نگاه کن","examples":[{"de":"Guck mal, wie schön der Sonnenuntergang ist!","en":"Look how beautiful the sunset is!","ru":"Смотри, какой красивый закат!","vi":"Hãy nhìn hoàng hôn đẹp làm sao!","fa":"ببین غروب چقدر زیباست"},{"de":"Die Kinder gucken abends gern fern.","en":"In the evening the children like to watch TV.","ru":"По вечерам дети любят смотреть телевизор.","vi":"Trẻ em thích xem TV vào buổi tối.","fa":"بچه ها دوست دارند عصرها تلویزیون تماشا کنند."}]},{"word":"gültig","en":"valid","ru":"действительный","vi":"hợp lệ","fa":"معتبر","examples":[{"de":"Mein Reisepass ist noch zwei Jahre gültig.","en":"My passport is still valid for two years.","ru":"Мой паспорт действителен ещё два года.","vi":"Hộ chiếu của tôi vẫn còn hiệu lực trong hai năm.","fa":"پاسپورت من هنوز دو سال اعتبار دارد."},{"de":"Das Ticket ist nur heute gültig.","en":"The ticket is only valid today.","ru":"Билет действителен только сегодня.","vi":"Vé chỉ có hiệu lực trong ngày hôm nay.","fa":"بلیط فقط امروز معتبر است."}]},{"word":"günstig","en":"cheap; favorable","ru":"выгодный, недорогой","vi":"giá rẻ","fa":"ارزان","examples":[{"de":"In diesem Geschäft sind die Preise sehr günstig.","en":"In this shop the prices are very cheap.","ru":"В этом магазине цены очень выгодные.","vi":"Ở cửa hàng này giá cả rất phải chăng.","fa":"در این فروشگاه قیمت ها بسیار مقرون به صرفه است."},{"de":"Wir haben einen günstigen Flug gefunden.","en":"We found an affordable flight.","ru":"Мы нашли недорогой авиабилет.","vi":"Chúng tôi tìm thấy một chuyến bay giá rẻ.","fa":"یک پرواز ارزان پیدا کردیم."}]},{"word":"gut","en":"good; well","ru":"хороший, хорошо","vi":"tốt","fa":"خوب","examples":[{"de":"Das Essen in diesem Restaurant ist wirklich gut.","en":"The food in this restaurant is really good.","ru":"Еда в этом ресторане действительно хорошая.","vi":"Đồ ăn ở nhà hàng này thực sự rất ngon.","fa":"غذاهای این رستوران واقعا عالی است."},{"de":"Mir geht es heute gut.","en":"I'm doing well today.","ru":"Сегодня я чувствую себя хорошо.","vi":"Hôm nay tôi ổn.","fa":"امروز خوبم"}]},{"word":"die Gymnastik","en":"gymnastics; exercise","ru":"гимнастика","vi":"thể dục dụng cụ","fa":"ژیمناستیک","examples":[{"de":"Jeden Morgen macht sie zehn Minuten Gymnastik.","en":"Every morning she does ten minutes of exercise.","ru":"Каждое утро она делает десятиминутную гимнастику.","vi":"Mỗi buổi sáng cô ấy tập thể dục mười phút.","fa":"او هر روز صبح ده دقیقه ژیمناستیک انجام می دهد."},{"de":"In der Schule haben wir zweimal pro Woche Gymnastik.","en":"At school we have gymnastics twice a week.","ru":"В школе у нас гимнастика два раза в неделю.","vi":"Ở trường chúng tôi có thể dục dụng cụ hai lần một tuần.","fa":"در مدرسه هفته ای دو بار ژیمناستیک داریم."}]},{"word":"das Haar","en":"hair","ru":"волосы","vi":"mái tóc","fa":"مو","examples":[{"de":"Sie hat lange, dunkle Haare.","en":"She has long, dark hair.","ru":"У неё длинные тёмные волосы.","vi":"Cô ấy có mái tóc dài và đen.","fa":"او موهای بلند و تیره ای دارد."},{"de":"Er kämmt sich jeden Morgen die Haare.","en":"He combs his hair every morning.","ru":"Он расчёсывает волосы каждое утро.","vi":"Anh ấy chải tóc vào mỗi buổi sáng.","fa":"هر روز صبح موهایش را شانه می کند."}]},{"word":"haben","en":"to have","ru":"иметь","vi":"có","fa":"دارند","examples":[{"de":"Ich habe heute leider keine Zeit.","en":"Unfortunately I don't have time today.","ru":"К сожалению, сегодня у меня нет времени.","vi":"Thật không may là hôm nay tôi không có thời gian.","fa":"متاسفانه امروز وقت ندارم"},{"de":"Wir haben ein kleines Auto.","en":"We have a small car.","ru":"У нас маленькая машина.","vi":"Chúng tôi có một chiếc xe nhỏ.","fa":"ما یک ماشین کوچک داریم."}]},{"word":"Habt ihr noch Fragen?","en":"Do you have any questions? (inviting questions)","ru":"Есть ли у вас вопросы? (приглашение к вопросам)","vi":"Bạn có câu hỏi nào không?","fa":"آیا سوالی دارید؟","examples":[{"de":"Das war meine Präsentation. Habt ihr noch Fragen?","en":"That was my presentation. Do you have any questions?","ru":"Это была моя презентация. Есть ли у вас вопросы?","vi":"Đó là bài thuyết trình của tôi. Bạn vẫn còn thắc mắc?","fa":"این ارائه من بود. آیا هنوز سوالی دارید؟"}]},{"word":"das Hackfleisch","en":"minced meat; ground meat","ru":"фарш","vi":"thịt băm","fa":"گوشت چرخ کرده","examples":[{"de":"Für die Soße brauchen wir 500 Gramm Hackfleisch.","en":"For the sauce we need 500 grams of minced meat.","ru":"Для соуса нам нужно 500 граммов фарша.","vi":"Đối với nước sốt chúng ta cần 500 gram thịt băm.","fa":"برای سس به 500 گرم گوشت چرخ کرده نیاز داریم."},{"de":"Sie macht aus Hackfleisch leckere Frikadellen.","en":"She makes delicious meatballs from minced meat.","ru":"Она делает вкусные котлеты из фарша.","vi":"Cô ấy làm món thịt viên thơm ngon từ thịt băm.","fa":"او از گوشت چرخ کرده کوفته های خوشمزه درست می کند."}]},{"word":"der Hafen","en":"harbor; port","ru":"порт, гавань","vi":"cảng","fa":"بندر","examples":[{"de":"Das Schiff verlässt heute den Hafen.","en":"The ship is leaving the harbor today.","ru":"Сегодня корабль покидает порт.","vi":"Hôm nay tàu rời cảng.","fa":"کشتی امروز بندر را ترک می کند."},{"de":"Hamburg hat einen der größten Häfen Europas.","en":"Hamburg has one of the largest ports in Europe.","ru":"В Гамбурге находится один из крупнейших портов Европы.","vi":"Hamburg có một trong những cảng lớn nhất ở châu Âu.","fa":"هامبورگ یکی از بزرگترین بنادر اروپا را دارد."}]},{"word":"die Haftpflicht","en":"liability; third-party liability (insurance)","ru":"гражданская ответственность; страхование ответственности (ОСАГО)","vi":"trách nhiệm pháp lý","fa":"مسئولیت","examples":[{"de":"Jeder Autofahrer braucht eine Haftpflicht.","en":"Every driver needs third-party liability insurance.","ru":"Каждому автомобилисту нужна страховка ответственности.","vi":"Mọi người lái xe đều cần có bảo hiểm trách nhiệm.","fa":"هر راننده ای نیاز به بیمه مسئولیت دارد."},{"de":"Die Haftpflicht deckt Schäden, die du anderen zufügst.","en":"The liability insurance covers damage you cause to others.","ru":"Страховка ответственности покрывает ущерб, который ты причиняешь другим.","vi":"Trách nhiệm bồi thường thiệt hại mà bạn gây ra cho người khác.","fa":"مسئولیت خساراتی را که به دیگران وارد می کنید پوشش می دهد."},{"de":"Ohne Haftpflicht darfst du nicht fahren.","en":"You are not allowed to drive without liability insurance.","ru":"Без страховки ответственности ездить нельзя.","vi":"Bạn không được phép lái xe mà không có trách nhiệm pháp lý.","fa":"شما مجاز به رانندگی بدون مسئولیت نیستید."}]},{"word":"hageln","en":"to hail","ru":"идти (о граде)","vi":"mưa đá","fa":"تگرگ","examples":[{"de":"Es hagelt so stark, dass wir zu Hause bleiben.","en":"It's hailing so hard that we're staying home.","ru":"Град такой сильный, что мы остаёмся дома.","vi":"Trời mưa đá dữ dội đến nỗi chúng tôi phải ở nhà.","fa":"آنقدر باران می بارید که مجبور شدیم در خانه بمانیم."},{"de":"Gestern hat es plötzlich gehagelt.","en":"Yesterday it suddenly hailed.","ru":"Вчера внезапно пошёл град.","vi":"Hôm qua nó đột nhiên ca ngợi.","fa":"دیروز ناگهان تگرگ آمد."}]},{"word":"das Hähnchen/Hühnchen","en":"chicken (as food)","ru":"курица, цыплёнок (как блюдо)","vi":"con gà/gà","fa":"مرغ/مرغ","examples":[{"de":"Zum Mittagessen gibt es heute Hähnchen mit Reis.","en":"For lunch today there's chicken with rice.","ru":"Сегодня на обед курица с рисом.","vi":"Bữa trưa hôm nay chúng tôi có cơm gà.","fa":"برای ناهار امروز مرغ با برنج داریم."},{"de":"Er bestellt im Restaurant gern ein gegrilltes Hühnchen.","en":"In restaurants he likes to order grilled chicken.","ru":"В ресторане он любит заказывать курицу-гриль.","vi":"Anh ấy thích gọi món gà nướng ở nhà hàng.","fa":"او دوست دارد در رستوران مرغ کبابی سفارش دهد."}]},{"word":"halb","en":"half","ru":"половина; наполовину","vi":"một nửa","fa":"نصف","examples":[{"de":"Ich nehme nur ein halbes Brot.","en":"I'll take only half a loaf of bread.","ru":"Я возьму только полбулки хлеба.","vi":"Tôi chỉ lấy nửa ổ bánh mì thôi.","fa":"من فقط نصف قرص نان می گیرم."},{"de":"Es ist jetzt halb neun.","en":"It's now half past eight.","ru":"Сейчас половина девятого.","vi":"Bây giờ là tám giờ rưỡi.","fa":"الان ساعت هشت و نیم است."}]},{"word":"halbtags","en":"part-time (half-day)","ru":"на полставки, полдня","vi":"nửa ngày","fa":"نیم روز","examples":[{"de":"Nach der Geburt ihres Kindes arbeitet sie nur noch halbtags.","en":"After the birth of her child she now only works part-time.","ru":"После рождения ребёнка она теперь работает только на полставки.","vi":"Sau khi sinh con, cô chỉ làm việc bán thời gian.","fa":"او پس از تولد فرزندش فقط به صورت پاره وقت کار می کند."},{"de":"Er sucht eine Stelle, bei der er halbtags arbeiten kann.","en":"He is looking for a job where he can work part-time.","ru":"Он ищет работу, где можно работать полдня.","vi":"Anh ấy đang tìm kiếm một công việc có thể làm việc bán thời gian.","fa":"او به دنبال شغلی است که بتواند به صورت پاره وقت کار کند."},{"de":"Halbtags zu arbeiten passt besser zu meinem Familienleben.","en":"Working part-time suits my family life better.","ru":"Работа на полставки лучше подходит моей семейной жизни.","vi":"Làm việc bán thời gian phù hợp hơn với cuộc sống gia đình tôi.","fa":"کار پاره وقت با زندگی خانوادگی من سازگاری بیشتری دارد."}]},{"word":"die Hälfte","en":"half","ru":"половина","vi":"một nửa","fa":"نصف","examples":[{"de":"Die Hälfte der Schüler war krank.","en":"Half of the students were sick.","ru":"Половина учеников болела.","vi":"Một nửa số học sinh bị ốm.","fa":"نیمی از دانش آموزان بیمار بودند."},{"de":"Ich gebe dir die Hälfte von meinem Kuchen.","en":"I'll give you half of my cake.","ru":"Я отдам тебе половину своего пирога.","vi":"Tôi sẽ đưa cho bạn một nửa chiếc bánh của tôi.","fa":"نصف کیکم رو بهت میدم"}]},{"word":"die Halle","en":"hall","ru":"зал","vi":"hội trường","fa":"سالن","examples":[{"de":"Das Konzert findet in einer großen Halle statt.","en":"The concert takes place in a large hall.","ru":"Концерт проходит в большом зале.","vi":"Buổi hòa nhạc diễn ra trong một hội trường lớn.","fa":"کنسرت در یک سالن بزرگ برگزار می شود."},{"de":"Die Sportler trainieren in der Halle.","en":"The athletes train in the hall.","ru":"Спортсмены тренируются в зале.","vi":"Các vận động viên tập luyện trong hội trường.","fa":"ورزشکاران در سالن تمرین می کنند."}]},{"word":"das Hallenbad","en":"indoor swimming pool","ru":"крытый бассейн","vi":"bể bơi trong nhà","fa":"استخر سرپوشیده","examples":[{"de":"Im Winter gehen wir oft ins Hallenbad.","en":"In winter we often go to the indoor pool.","ru":"Зимой мы часто ходим в крытый бассейн.","vi":"Vào mùa đông chúng tôi thường đến bể bơi trong nhà.","fa":"در زمستان اغلب به استخر سرپوشیده می رویم."},{"de":"Das Hallenbad hat täglich von acht bis zwanzig Uhr geöffnet.","en":"The indoor pool is open daily from eight until eight in the evening.","ru":"Крытый бассейн открыт ежедневно с восьми до восьми вечера.","vi":"Hồ bơi trong nhà mở cửa hàng ngày từ 8 giờ sáng đến 8 giờ tối.","fa":"استخر سرپوشیده همه روزه از ساعت 8 صبح تا 8 بعد از ظهر باز است."},{"de":"Im Hallenbad ist das Wasser angenehm warm.","en":"The water in the indoor pool is pleasantly warm.","ru":"Вода в крытом бассейне приятно тёплая.","vi":"Nước ở bể bơi trong nhà ấm áp dễ chịu.","fa":"آب در استخر سرپوشیده به طرز دلپذیری گرم است."}]},{"word":"hallo","en":"hello","ru":"привет","vi":"xin chào","fa":"سلام","examples":[{"de":"Hallo, wie geht es dir?","en":"Hello, how are you?","ru":"Привет, как дела?","vi":"Xin chào, bạn khỏe không?","fa":"سلام حالتون چطوره؟"},{"de":"Sie ruft \"Hallo!\" und winkt uns zu.","en":"She calls \"Hello!\" and waves to us.","ru":"Она кричит «Привет!» и машет нам рукой.","vi":"Cô ấy gọi \"Xin chào!\" và vẫy tay với chúng tôi.","fa":"او صدا می زند \"سلام!\" و برای ما دست تکان می دهد"}]},{"word":"der Hals","en":"neck; throat","ru":"шея, горло","vi":"cái cổ","fa":"گردن","examples":[{"de":"Mein Hals tut weh, ich habe wohl eine Erkältung.","en":"My throat hurts, I probably have a cold.","ru":"У меня болит горло, наверное, я простудился.","vi":"Cổ họng tôi đau quá, tôi nghĩ mình bị cảm lạnh.","fa":"گلویم درد می کند، فکر کنم سرما خورده ام."},{"de":"Sie trägt eine Kette um den Hals.","en":"She wears a necklace around her neck.","ru":"Она носит цепочку на шее.","vi":"Cô ấy đeo một sợi dây chuyền quanh cổ.","fa":"زنجیر به گردنش می بندد."}]},{"word":"Hals über Kopf","en":"head over heels / in a great rush","ru":"сломя голову, второпях","vi":"lao đầu vào gót chân / rất vội vàng","fa":"سر به پا / در عجله بزرگ","examples":[{"de":"Wir mussten Hals über Kopf die Wohnung verlassen.","en":"We had to leave the flat head over heels.","ru":"Нам пришлось сломя голову покинуть квартиру.","vi":"Chúng tôi phải vội vã rời khỏi căn hộ.","fa":"مجبور شدیم با عجله از آپارتمان خارج شویم."}]},{"word":"Hals- und Beinbruch","en":"break a leg / good luck (colloquial)","ru":"ни пуха ни пера (пожелание удачи)","vi":"gãy chân/chúc may mắn","fa":"شکستن پا / موفق باشید","examples":[{"de":"Du hast gleich dein Vorstellungsgespräch — Hals- und Beinbruch!","en":"Your interview is coming up — break a leg!","ru":"У тебя скоро собеседование — ни пуха ни пера!","vi":"Bạn sắp có cuộc phỏng vấn - thật là đau đầu!","fa":"شما در شرف انجام مصاحبه هستید - این یک سردرد است!"}]},{"word":"halt","en":"just, simply (filler particle); stop! (interjection)","ru":"просто, именно (частица); стоп!","vi":"dừng lại","fa":"توقف","examples":[{"de":"Das ist halt so, man kann nichts ändern.","en":"That's just how it is, you can't change anything.","ru":"Так уж есть, ничего не поделаешь.","vi":"Vốn dĩ là vậy, bạn không thể thay đổi được gì cả.","fa":"همین طور است، شما نمی توانید چیزی را تغییر دهید."},{"de":"\"Halt!\", rief der Polizist dem Fahrer zu.","en":"\"Stop!\" the police officer shouted to the driver.","ru":"«Стоп!» — крикнул полицейский водителю.","vi":"\"Dừng lại!\" viên cảnh sát hét vào mặt tài xế.","fa":"\"ایست کن!\" افسر پلیس به راننده فریاد زد."}]},{"word":"haltbar","en":"durable; non-perishable, keeps well","ru":"прочный; долго хранящийся","vi":"bền bỉ","fa":"بادوام","examples":[{"de":"Diese Milch ist noch bis nächste Woche haltbar.","en":"This milk is still good until next week.","ru":"Это молоко годно ещё до следующей недели.","vi":"Sữa này sẽ kéo dài đến tuần sau.","fa":"این شیر تا هفته آینده ماندگاری دارد."},{"de":"Die Schuhe sind aus haltbarem Material.","en":"The shoes are made of durable material.","ru":"Обувь сделана из прочного материала.","vi":"Giày được làm từ chất liệu bền đẹp.","fa":"کفش ها از مواد بادوام ساخته شده اند."}]},{"word":"halten","en":"to hold; to stop (of a vehicle)","ru":"держать; останавливаться","vi":"giữ","fa":"نگه دارید","examples":[{"de":"Kannst du bitte kurz meine Tasche halten?","en":"Can you hold my bag for a moment, please?","ru":"Можешь ненадолго подержать мою сумку?","vi":"Bạn có thể giữ túi của tôi một lúc được không?","fa":"میشه لطفا یه لحظه کیفم رو نگه دارید؟"},{"de":"Der Bus hält direkt vor unserem Haus.","en":"The bus stops right in front of our house.","ru":"Автобус останавливается прямо перед нашим домом.","vi":"Xe buýt dừng ngay trước nhà chúng tôi.","fa":"اتوبوس درست جلوی خانه ما می ایستد."}]},{"word":"die Haltung","en":"posture, pose; also stance/attitude","ru":"осанка, поза; также позиция, отношение","vi":"thái độ","fa":"نگرش","examples":[{"de":"Achte beim Sitzen auf eine gerade Haltung.","en":"Mind your posture and sit up straight.","ru":"Сидя, следи за прямой осанкой.","vi":"Hãy chắc chắn rằng bạn duy trì tư thế thẳng khi ngồi.","fa":"هنگام نشستن مطمئن شوید که حالت مستقیم خود را حفظ کنید."},{"de":"Die Lehrerin korrigierte sanft die Haltung der Schüler.","en":"The teacher gently corrected the pupils' posture.","ru":"Учительница мягко поправляла осанку учеников.","vi":"Cô giáo nhẹ nhàng sửa lại tư thế cho học sinh.","fa":"معلم به آرامی وضعیت دانش آموزان را اصلاح کرد."},{"de":"Eine aufrechte Haltung wirkt selbstbewusst.","en":"An upright posture comes across as confident.","ru":"Прямая осанка производит впечатление уверенности.","vi":"Một tư thế thẳng đứng có vẻ tự tin.","fa":"حالت ایستاده مطمئن به نظر می رسد."}]},{"word":"der Hammer","en":"hammer","ru":"молоток","vi":"cái búa","fa":"چکش","examples":[{"de":"Er braucht einen Hammer, um den Nagel einzuschlagen.","en":"He needs a hammer to drive in the nail.","ru":"Ему нужен молоток, чтобы забить гвоздь.","vi":"Anh ta cần một cái búa để đóng đinh.","fa":"او به یک چکش نیاز دارد تا در میخ بکوبد."},{"de":"Der Hammer liegt in der Werkzeugkiste.","en":"The hammer is in the toolbox.","ru":"Молоток лежит в ящике с инструментами.","vi":"Cái búa ở trong hộp dụng cụ.","fa":"چکش در جعبه ابزار است."}]},{"word":"die Hand","en":"hand","ru":"рука","vi":"bàn tay","fa":"دست","examples":[{"de":"Gib mir bitte deine Hand.","en":"Please give me your hand.","ru":"Дай мне, пожалуйста, свою руку.","vi":"Xin hãy đưa tay cho tôi.","fa":"لطفا دستت را به من بده"},{"de":"Sie wäscht sich vor dem Essen die Hände.","en":"She washes her hands before eating.","ru":"Она моет руки перед едой.","vi":"Cô rửa tay trước khi ăn.","fa":"قبل از غذا دست هایش را می شویند."}]},{"word":"der Handel","en":"trade; commerce","ru":"торговля; сделка","vi":"việc buôn bán","fa":"تجارت","examples":[{"de":"Der Handel zwischen den beiden Ländern wächst.","en":"Trade between the two countries is growing.","ru":"Торговля между двумя странами растёт.","vi":"Thương mại giữa hai nước ngày càng phát triển.","fa":"تجارت بین دو کشور در حال رشد است."},{"de":"Er arbeitet im internationalen Handel.","en":"He works in international trade.","ru":"Он работает в международной торговле.","vi":"Anh ấy làm việc trong lĩnh vực thương mại quốc tế.","fa":"او در تجارت بین المللی کار می کند."},{"de":"Der Handel mit Gebrauchtwagen ist sein Geschäft.","en":"Dealing in used cars is his business.","ru":"Торговля подержанными машинами — его дело.","vi":"Buôn bán xe cũ là việc của anh ấy.","fa":"تجارت خودروهای دست دوم کار اوست."}]},{"word":"handeln","en":"to act; to trade/deal","ru":"действовать; торговать","vi":"hành động","fa":"عمل کنید","examples":[{"de":"In dieser schwierigen Situation müssen wir schnell handeln.","en":"In this difficult situation we have to act quickly.","ru":"В этой сложной ситуации нам нужно действовать быстро.","vi":"Trong tình thế khó khăn này chúng ta phải hành động nhanh chóng.","fa":"در این شرایط سخت باید سریع عمل کنیم."},{"de":"Er handelt mit gebrauchten Autos.","en":"He trades in used cars.","ru":"Он торгует подержанными автомобилями.","vi":"Anh ấy kinh doanh xe cũ.","fa":"او با ماشین های دست دوم معامله می کند."}]},{"word":"der Händler","en":"dealer, trader, merchant","ru":"торговец, продавец","vi":"người buôn bán","fa":"فروشنده","examples":[{"de":"Der Händler auf dem Markt verkauft frisches Gemüse.","en":"The trader at the market sells fresh vegetables.","ru":"Торговец на рынке продаёт свежие овощи.","vi":"Người buôn bán ở chợ bán rau tươi.","fa":"تاجر در بازار سبزی تازه می فروشد."},{"de":"Wir haben das Auto direkt beim Händler gekauft.","en":"We bought the car directly from the dealer.","ru":"Мы купили машину напрямую у продавца.","vi":"Chúng tôi mua xe trực tiếp từ đại lý.","fa":"ما ماشین را مستقیما از نمایندگی خریدیم."},{"de":"Ein ehrlicher Händler nennt dir immer den richtigen Preis.","en":"An honest dealer always tells you the right price.","ru":"Честный продавец всегда назовёт тебе правильную цену.","vi":"Một đại lý trung thực sẽ luôn cung cấp cho bạn mức giá hợp lý.","fa":"یک فروشنده صادق همیشه قیمت مناسب را به شما می دهد."}]},{"word":"die Händlerin","en":"dealer, trader, merchant (female)","ru":"торговка, продавщица","vi":"người buôn bán","fa":"فروشنده","examples":[{"de":"Die Händlerin am Stand kennt alle ihre Stammkunden.","en":"The trader at the stall knows all her regular customers.","ru":"Продавщица у прилавка знает всех своих постоянных клиентов.","vi":"Người bán hàng ở quầy biết tất cả các khách hàng thường xuyên của cô.","fa":"فروشنده در غرفه همه مشتریان دائمی خود را می شناسد."},{"de":"Eine freundliche Händlerin beriet uns beim Einkauf.","en":"A friendly trader advised us during our shopping.","ru":"Приветливая продавщица консультировала нас при покупке.","vi":"Một đại lý thân thiện đã tư vấn cho chúng tôi về việc mua hàng của chúng tôi.","fa":"یک فروشنده دوستانه به ما در مورد خرید مشاوره داد."},{"de":"Die Händlerin gab mir das Wechselgeld zurück.","en":"The trader gave me back my change.","ru":"Торговка вернула мне сдачу.","vi":"Người bán hàng đã trả lại tiền lẻ cho tôi.","fa":"فروشنده پول خرد را به من پس داد."}]},{"word":"der Handstand","en":"a handstand (balancing upside down on the hands)","ru":"стойка на руках","vi":"trồng chuối","fa":"the handstand","examples":[{"de":"Zwanzig Zwerge machen einen Handstand.","en":"Twenty dwarves do a handstand.","ru":"Двадцать гномов делают стойку на руках.","vi":"Hai mươi người lùn thực hiện động tác trồng cây chuối.","fa":"بیست کوتوله روی دست ایستاده اند."},{"de":"Im Turnunterricht übten wir den Handstand an der Wand.","en":"In PE we practised the handstand against the wall.","ru":"На физкультуре мы отрабатывали стойку на руках у стены.","vi":"Trong lớp thể dục, chúng tôi tập trồng cây chuối trên tường.","fa":"در کلاس بدنسازی، ایستادن روی دیوار را تمرین می‌کردیم."},{"de":"Sie hielt den Handstand mehrere Sekunden lang ganz ruhig.","en":"She held the handstand quite still for several seconds.","ru":"Она держала стойку на руках совершенно неподвижно несколько секунд.","vi":"Cô ấy giữ yên cây trồng chuối trong vài giây.","fa":"پایه دستی را برای چند ثانیه خیلی ثابت نگه داشت."}]},{"word":"das Handtuch werfen","en":"to throw in the towel / give up","ru":"выбросить полотенце, сдаться","vi":"bỏ cuộc / bỏ cuộc","fa":"حوله انداختن / تسلیم شدن","examples":[{"de":"Nach dem dritten Versuch wollte sie das Handtuch werfen.","en":"After the third attempt she wanted to throw in the towel.","ru":"После третьей попытки она хотела сдаться.","vi":"Sau lần thử thứ ba, cô ấy muốn bỏ cuộc.","fa":"پس از تلاش سوم، او می خواست حوله را پرتاب کند."}]},{"word":"die Handwerkerin","en":"craftswoman; tradeswoman","ru":"мастерица, ремесленница","vi":"người phụ nữ thủ công","fa":"صنعتگر","examples":[{"de":"Die Handwerkerin repariert das kaputte Fenster.","en":"The tradeswoman is repairing the broken window.","ru":"Мастерица чинит сломанное окно.","vi":"Người thợ thủ công sửa lại cửa sổ bị vỡ.","fa":"صنعتگر پنجره شکسته را تعمیر می کند."},{"de":"Als Handwerkerin arbeitet sie oft auf Baustellen.","en":"As a tradeswoman, she often works on construction sites.","ru":"Как мастерица, она часто работает на стройках.","vi":"Là một thợ thủ công, cô thường xuyên làm việc ở các công trường xây dựng.","fa":"به عنوان یک صنعتگر، او اغلب در سایت های ساختمانی کار می کند."}]},{"word":"das Handy","en":"mobile phone; cell phone","ru":"мобильный телефон","vi":"điện thoại di động","fa":"تلفن همراه","examples":[{"de":"Ich habe mein Handy leider zu Hause vergessen.","en":"Unfortunately I forgot my phone at home.","ru":"К сожалению, я забыл телефон дома.","vi":"Thật không may, tôi lại để quên điện thoại di động ở nhà.","fa":"متاسفانه تلفن همراهم را در خانه فراموش کردم."},{"de":"Kinder bekommen heute schon früh ein Handy.","en":"Nowadays children get a cell phone quite early.","ru":"Сегодня дети получают мобильный телефон довольно рано.","vi":"Trẻ em ngày nay có điện thoại di động sớm.","fa":"این روزها بچه ها زودتر تلفن همراه می گیرند."}]},{"word":"hängen","en":"to hang","ru":"висеть; вешать","vi":"treo","fa":"آویزان کردن","examples":[{"de":"An der Wand hängt ein altes Familienfoto.","en":"An old family photo hangs on the wall.","ru":"На стене висит старая семейная фотография.","vi":"Có một bức ảnh cũ của gia đình treo trên tường.","fa":"یک عکس خانوادگی قدیمی روی دیوار آویزان است."},{"de":"Sie hängt die Wäsche zum Trocknen auf.","en":"She hangs the laundry up to dry.","ru":"Она развешивает бельё для сушки.","vi":"Cô ấy phơi đồ giặt ra ngoài.","fa":"او لباس‌ها را آویزان می‌کند تا خشک شوند."}]},{"word":"die Harmonie","en":"harmony","ru":"гармония","vi":"sự hòa hợp","fa":"هارمونی","examples":[{"de":"Tanz und Musik bilden eine vollkommene Harmonie.","en":"Dance and music form a perfect harmony.","ru":"Танец и музыка образуют совершенную гармонию.","vi":"Khiêu vũ và âm nhạc tạo thành một sự hòa hợp hoàn hảo.","fa":"رقص و موسیقی یک هارمونی کامل را تشکیل می دهند."},{"de":"In der Familie herrscht endlich wieder Harmonie.","en":"Harmony reigns in the family once again at last.","ru":"В семье наконец снова царит гармония.","vi":"Cuối cùng cũng có sự hòa thuận trong gia đình trở lại.","fa":"بالاخره دوباره هماهنگی در خانواده برقرار می شود."},{"de":"Die Farben des Gemäldes stehen in vollkommener Harmonie zueinander.","en":"The colours of the painting are in perfect harmony with one another.","ru":"Цвета на картине находятся в совершенной гармонии друг с другом.","vi":"Màu sắc của bức tranh hoàn toàn hài hòa với nhau.","fa":"رنگ های نقاشی با یکدیگر هماهنگی کامل دارند."}]},{"word":"hart","en":"hard","ru":"твёрдый, жёсткий","vi":"cứng","fa":"سخت","examples":[{"de":"Das Brot ist schon ganz hart geworden.","en":"The bread has already become quite hard.","ru":"Хлеб уже стал совсем твёрдым.","vi":"Bánh mì đã trở nên rất cứng rồi.","fa":"نان در حال حاضر بسیار سفت شده است."},{"de":"Er arbeitet sehr hart für seine Familie.","en":"He works very hard for his family.","ru":"Он очень тяжело работает ради своей семьи.","vi":"Anh ấy làm việc rất chăm chỉ cho gia đình mình.","fa":"او برای خانواده اش خیلی زحمت می کشد."}]},{"word":"hassen","en":"to hate","ru":"ненавидеть","vi":"ghét","fa":"نفرت","examples":[{"de":"Sie hasst es, morgens früh aufzustehen.","en":"She hates getting up early in the morning.","ru":"Она ненавидит рано вставать по утрам.","vi":"Cô ấy ghét việc phải dậy sớm vào buổi sáng.","fa":"او از صبح زود بیدار شدن متنفر است."},{"de":"Ich hasse Streit in der Familie.","en":"I hate arguments in the family.","ru":"Я ненавижу ссоры в семье.","vi":"Tôi ghét những cuộc cãi vã trong gia đình.","fa":"من از بحث و جدل در خانواده متنفرم."}]},{"word":"hässlich","en":"ugly","ru":"некрасивый, уродливый","vi":"xấu xí","fa":"زشت","examples":[{"de":"Das alte Gebäude sieht ziemlich hässlich aus.","en":"The old building looks quite ugly.","ru":"Старое здание выглядит довольно некрасиво.","vi":"Tòa nhà cũ trông khá xấu xí.","fa":"ساختمان قدیمی بسیار زشت به نظر می رسد."},{"de":"Er hat ein hässliches Wort benutzt.","en":"He used an ugly word.","ru":"Он использовал некрасивое слово.","vi":"Anh ta dùng một từ xấu xí.","fa":"کلمه زشتی به کار برد."}]},{"word":"Das hat sowohl Vorteile als auch Nachteile","en":"That has both advantages and disadvantages (balanced view)","ru":"Это имеет как плюсы, так и минусы (сбалансированно)","vi":"Điều đó có cả ưu điểm và nhược điểm","fa":"که هم مزایا و هم معایبی دارد","examples":[{"de":"Homeoffice hat sowohl Vorteile als auch Nachteile.","en":"Working from home has both advantages and disadvantages.","ru":"Удалённая работа имеет как плюсы, так и минусы.","vi":"Làm việc tại nhà có cả ưu điểm và nhược điểm.","fa":"کار در خانه هم مزایا و هم معایبی دارد."}]},{"word":"häufig","en":"frequent; frequently","ru":"частый, часто","vi":"thường xuyên","fa":"اغلب","examples":[{"de":"Er macht häufig denselben Fehler.","en":"He frequently makes the same mistake.","ru":"Он часто допускает одну и ту же ошибку.","vi":"Anh ấy thường mắc phải sai lầm tương tự.","fa":"او اغلب همین اشتباه را انجام می دهد."},{"de":"Häufige Kopfschmerzen können ein Zeichen von Stress sein.","en":"Frequent headaches can be a sign of stress.","ru":"Частые головные боли могут быть признаком стресса.","vi":"Đau đầu thường xuyên có thể là dấu hiệu của căng thẳng.","fa":"سردردهای مکرر می تواند نشانه استرس باشد."}]},{"word":"die Häufigkeit","en":"frequency","ru":"частота (встречаемости)","vi":"tần số","fa":"فرکانس","examples":[{"de":"Wir messen die Häufigkeit jedes Wortes.","en":"We measure the frequency of each word.","ru":"Мы измеряем частоту каждого слова.","vi":"Chúng tôi đo tần số của mỗi từ.","fa":"فرکانس هر کلمه را اندازه می گیریم."},{"de":"Die Häufigkeit der Fehler nimmt ab.","en":"The frequency of the errors is decreasing.","ru":"Частота ошибок снижается.","vi":"Tần suất lỗi giảm.","fa":"تعداد خطاها کاهش می یابد."},{"de":"Mit welcher Häufigkeit tritt dieser Wert auf?","en":"With what frequency does this value occur?","ru":"С какой частотой встречается это значение?","vi":"Giá trị này xảy ra thường xuyên như thế nào?","fa":"این مقدار چند بار رخ می دهد؟"}]},{"word":"Haupt-","en":"prefix meaning \"main, chief\" (e.g. \"Hauptstadt\" = capital city)","ru":"приставка со значением «главный, основной» (напр. Hauptstadt — столица)","vi":"chính","fa":"اصلی","examples":[{"de":"Berlin ist die Hauptstadt von Deutschland.","en":"Berlin is the capital of Germany.","ru":"Берлин — столица Германии.","vi":"Berlin là thủ đô của Đức.","fa":"برلین پایتخت آلمان است."},{"de":"Der Hauptbahnhof liegt im Zentrum der Stadt.","en":"The main train station is located in the city center.","ru":"Главный вокзал находится в центре города.","vi":"Nhà ga xe lửa chính nằm ở trung tâm thành phố.","fa":"ایستگاه اصلی قطار در مرکز شهر قرار دارد."}]},{"word":"der Hauptbahnhof","en":"central station; main railway station","ru":"центральный (главный) вокзал","vi":"nhà ga chính","fa":"ایستگاه اصلی","examples":[{"de":"Wir treffen uns um drei am Hauptbahnhof.","en":"We will meet at three at the central station.","ru":"Мы встречаемся в три у центрального вокзала.","vi":"Chúng ta sẽ gặp nhau ở ga xe lửa chính lúc ba giờ.","fa":"ساعت سه در ایستگاه اصلی قطار همدیگر را خواهیم دید."},{"de":"Vom Hauptbahnhof fahren Züge in alle Richtungen.","en":"Trains leave the central station in all directions.","ru":"С центрального вокзала поезда идут во все стороны.","vi":"Xe lửa chạy theo mọi hướng từ ga chính.","fa":"قطارها از ایستگاه اصلی در همه جهات حرکت می کنند."},{"de":"Der Hauptbahnhof liegt mitten in der Stadt.","en":"The central station is right in the middle of the city.","ru":"Центральный вокзал находится прямо в центре города.","vi":"Nhà ga xe lửa chính nằm ở giữa thành phố.","fa":"ایستگاه اصلی قطار در وسط شهر است."}]},{"word":"die Hauptsaison","en":"high season; peak season","ru":"высокий (пиковый) сезон","vi":"mùa cao điểm","fa":"فصل اوج","examples":[{"de":"In der Hauptsaison sind die Hotels oft ausgebucht.","en":"In the high season the hotels are often fully booked.","ru":"В высокий сезон отели часто забронированы полностью.","vi":"Vào mùa cao điểm, các khách sạn thường kín phòng.","fa":"در طول فصل شلوغ، هتل ها اغلب به طور کامل رزرو می شوند."},{"de":"Die Preise steigen während der Hauptsaison deutlich.","en":"Prices rise noticeably during the high season.","ru":"В высокий сезон цены заметно растут.","vi":"Giá tăng đáng kể trong mùa cao điểm.","fa":"قیمت ها در فصل اوج به طور قابل توجهی افزایش می یابد."},{"de":"Wir reisen lieber außerhalb der Hauptsaison.","en":"We prefer to travel outside the high season.","ru":"Мы предпочитаем путешествовать вне высокого сезона.","vi":"Chúng tôi thích đi du lịch ngoài mùa cao điểm.","fa":"ما ترجیح می دهیم خارج از فصل پیک سفر کنیم."}]},{"word":"die Hauptspeise","en":"main course","ru":"основное блюдо","vi":"món chính","fa":"غذای اصلی","examples":[{"de":"Als Hauptspeise nehme ich gegrillten Fisch.","en":"For the main course I'll have grilled fish.","ru":"На основное блюдо я возьму рыбу на гриле.","vi":"Món chính tôi có cá nướng.","fa":"برای غذای اصلی ماهی کبابی دارم."},{"de":"Die Hauptspeise wurde sehr heiß serviert.","en":"The main course was served very hot.","ru":"Основное блюдо подали очень горячим.","vi":"Món chính được phục vụ rất nóng.","fa":"غذای اصلی خیلی گرم سرو شد."},{"de":"Welche Hauptspeise empfehlen Sie?","en":"Which main course do you recommend?","ru":"Какое основное блюдо вы порекомендуете?","vi":"Bạn đề xuất món chính nào?","fa":"کدام غذای اصلی را پیشنهاد می کنید؟"}]},{"word":"das Haus","en":"house","ru":"дом","vi":"ngôi nhà","fa":"خانه","examples":[{"de":"Wir wohnen in einem kleinen Haus am Stadtrand.","en":"We live in a small house on the edge of town.","ru":"Мы живём в маленьком доме на окраине города.","vi":"Chúng tôi sống trong một ngôi nhà nhỏ ở ngoại ô thị trấn.","fa":"ما در یک خانه کوچک در حومه شهر زندگی می کنیم."},{"de":"Meine Eltern wollen ein neues Haus bauen.","en":"My parents want to build a new house.","ru":"Мои родители хотят построить новый дом.","vi":"Bố mẹ tôi muốn xây một ngôi nhà mới.","fa":"پدر و مادرم می خواهند یک خانه جدید بسازند."}]},{"word":"die Hausfrau","en":"housewife","ru":"домохозяйка","vi":"bà nội trợ","fa":"زن خانه دار","examples":[{"de":"Meine Mutter ist Hausfrau und kümmert sich um die Kinder.","en":"My mother is a housewife and takes care of the children.","ru":"Моя мама — домохозяйка и заботится о детях.","vi":"Mẹ tôi là một bà nội trợ và chăm sóc con cái.","fa":"مادرم خانه دار است و از بچه ها نگهداری می کند."},{"de":"Als Hausfrau hat sie den ganzen Tag viel zu tun.","en":"As a housewife, she has a lot to do all day.","ru":"Будучи домохозяйкой, она весь день очень занята.","vi":"Là một bà nội trợ, cô ấy có rất nhiều việc phải làm cả ngày.","fa":"او به عنوان یک زن خانه دار در تمام طول روز کارهای زیادی برای انجام دادن دارد."}]},{"word":"der Haushaltsgegenstand","en":"household item","ru":"предмет домашнего обихода","vi":"đồ gia dụng","fa":"کالای خانه","examples":[{"de":"Ein Wasserkocher ist ein praktischer Haushaltsgegenstand.","en":"A kettle is a practical household item.","ru":"Электрочайник — практичный предмет домашнего обихода.","vi":"Ấm đun nước là một vật dụng gia đình thiết thực.","fa":"کتری یک وسیله کاربردی خانگی است."},{"de":"Beim Umzug haben wir viele alte Haushaltsgegenstände verschenkt.","en":"When moving we gave away many old household items.","ru":"При переезде мы раздали много старых предметов домашнего обихода.","vi":"Khi chuyển đi, chúng tôi đã cho đi rất nhiều đồ cũ trong gia đình.","fa":"وقتی نقل مکان کردیم، بسیاری از وسایل خانه قدیمی را هدیه دادیم."},{"de":"Dieser Haushaltsgegenstand spart viel Zeit beim Kochen.","en":"This household item saves a lot of time when cooking.","ru":"Этот предмет экономит много времени на кухне.","vi":"Dieser Haushaltsgegenstand spart viel Zeit beim Kochen.","fa":"این وسیله خانگی در زمان پخت و پز بسیار صرفه جویی می کند."}]},{"word":"der Haushaltstipp","en":"household tip","ru":"совет по хозяйству, бытовой совет","vi":"mẹo gia đình","fa":"نوک خانوار","examples":[{"de":"Meine Oma kennt viele praktische Haushaltstipps.","en":"My grandmother knows lots of practical household tips.","ru":"Моя бабушка знает много практичных советов по хозяйству.","vi":"Bà tôi biết rất nhiều mẹo vặt gia đình thiết thực.","fa":"مادربزرگ من بسیاری از نکات کاربردی خانه را می داند."},{"de":"Im Internet findet man unzählige Haushaltstipps.","en":"You can find countless household tips on the internet.","ru":"В интернете можно найти бесчисленное множество бытовых советов.","vi":"Bạn có thể tìm thấy vô số lời khuyên gia đình trên internet.","fa":"شما می توانید نکات بی شماری برای خانه را در اینترنت بیابید."},{"de":"Dieser Haushaltstipp spart wirklich Zeit.","en":"This household tip really saves time.","ru":"Этот совет по хозяйству действительно экономит время.","vi":"Mẹo gia đình này thực sự tiết kiệm thời gian.","fa":"این نکته خانگی واقعا در زمان صرفه جویی می کند."}]},{"word":"der Hausmeister","en":"caretaker; janitor","ru":"комендант дома, завхоз","vi":"người chăm sóc","fa":"سرایدار","examples":[{"de":"Der Hausmeister repariert die kaputte Heizung.","en":"The caretaker is repairing the broken heating.","ru":"Комендант дома чинит сломанное отопление.","vi":"Người chăm sóc sửa chữa lò sưởi bị hỏng.","fa":"سرایدار بخاری خراب را تعمیر می کند."},{"de":"Wenn etwas kaputt ist, ruft man den Hausmeister.","en":"If something is broken, you call the caretaker.","ru":"Если что-то сломалось, вызывают завхоза.","vi":"Nếu có gì bị hỏng, bạn gọi người chăm sóc.","fa":"اگر چیزی شکسته است، با نگهبان تماس بگیرید."}]},{"word":"die Hausmeisterin","en":"caretaker; janitor (female)","ru":"комендантша, завхоз (женщина)","vi":"người chăm sóc","fa":"سرایدار","examples":[{"de":"Die Hausmeisterin kümmert sich um den Garten und das Treppenhaus.","en":"The caretaker takes care of the garden and the stairwell.","ru":"Комендантша заботится о саде и лестничной клетке.","vi":"Người chăm sóc chăm sóc khu vườn và cầu thang.","fa":"سرایدار از باغ و راه پله مراقبت می کند."},{"de":"Unsere Hausmeisterin ist sehr freundlich und hilfsbereit.","en":"Our caretaker is very friendly and helpful.","ru":"Наша комендантша очень дружелюбная и отзывчивая.","vi":"Người chăm sóc của chúng tôi rất thân thiện và hữu ích.","fa":"سرایدار ما بسیار دوستانه و مفید است."}]},{"word":"die Hausordnung","en":"house rules","ru":"правила проживания в доме, домовой распорядок","vi":"nội quy nhà","fa":"قوانین خانه","examples":[{"de":"Laut Hausordnung muss nach zehn Uhr Ruhe sein.","en":"According to the house rules it must be quiet after ten o'clock.","ru":"Согласно правилам дома, после десяти часов должна быть тишина.","vi":"Theo nội quy nhà, sau mười giờ phải im lặng.","fa":"طبق قوانین خانه، بعد از ساعت ده باید سکوت برقرار شود."},{"de":"Die Hausordnung hängt im Treppenhaus aus.","en":"The house rules are posted in the stairwell.","ru":"Правила проживания вывешены на лестничной клетке.","vi":"Nội quy nhà được dán ở cầu thang.","fa":"قوانین خانه در راه پله نصب شده است."},{"de":"Jeder Mieter muss die Hausordnung beachten.","en":"Every tenant has to observe the house rules.","ru":"Каждый жилец должен соблюдать правила дома.","vi":"Mọi người thuê nhà đều phải tuân thủ các nội quy của ngôi nhà.","fa":"هر مستأجری باید قوانین خانه را رعایت کند."}]},{"word":"das Haustier","en":"pet","ru":"домашнее животное","vi":"thú cưng","fa":"حیوان خانگی","examples":[{"de":"Habt ihr ein Haustier zu Hause?","en":"Do you have a pet at home?","ru":"У вас дома есть домашнее животное?","vi":"Nhà bạn có nuôi thú cưng không?","fa":"آیا حیوان خانگی در خانه دارید؟"},{"de":"Mein Lieblingshaustier ist eine kleine Katze.","en":"My favourite pet is a little cat.","ru":"Моё любимое домашнее животное — маленькая кошка.","vi":"Con vật cưng yêu thích của tôi là một con mèo nhỏ.","fa":"حیوان خانگی مورد علاقه من یک گربه کوچک است."},{"de":"In dieser Wohnung sind Haustiere nicht erlaubt.","en":"Pets are not allowed in this flat.","ru":"В этой квартире домашние животные не разрешены.","vi":"Vật nuôi không được phép vào căn hộ này.","fa":"ورود حیوانات خانگی به این آپارتمان ممنوع است."}]},{"word":"die Haut","en":"skin","ru":"кожа","vi":"da","fa":"پوست","examples":[{"de":"Im Sommer sollte man die Haut vor der Sonne schützen.","en":"In summer you should protect your skin from the sun.","ru":"Летом нужно защищать кожу от солнца.","vi":"Vào mùa hè bạn nên bảo vệ da khỏi ánh nắng mặt trời.","fa":"در تابستان باید از پوست خود در برابر نور خورشید محافظت کنید."},{"de":"Sie hat eine sehr empfindliche Haut.","en":"She has very sensitive skin.","ru":"У неё очень чувствительная кожа.","vi":"Cô ấy có làn da rất nhạy cảm.","fa":"او پوست بسیار حساسی دارد."}]},{"word":"der Hebel","en":"lever","ru":"рычаг","vi":"đòn bẩy","fa":"اهرم","examples":[{"de":"Mit einem langen Hebel kann man eine schwere Last heben.","en":"With a long lever you can lift a heavy load.","ru":"Длинным рычагом можно поднять тяжёлый груз.","vi":"Một đòn bẩy dài có thể được sử dụng để nâng một vật nặng.","fa":"برای بلند کردن بار سنگین می توان از یک اهرم بلند استفاده کرد."},{"de":"Der Hebel ist eine der einfachsten Maschinen der Physik.","en":"The lever is one of the simplest machines in physics.","ru":"Рычаг — одна из простейших машин в физике.","vi":"Đòn bẩy là một trong những cỗ máy đơn giản nhất trong vật lý.","fa":"اهرم یکی از ساده ترین ماشین های فیزیک است."},{"de":"Je länger der Hebel, desto weniger Kraft braucht man.","en":"The longer the lever, the less force you need.","ru":"Чем длиннее рычаг, тем меньше силы нужно.","vi":"Đòn bẩy càng dài thì bạn càng cần ít lực.","fa":"هر چه اهرم بلندتر باشد، به نیروی کمتری نیاز دارید."}]},{"word":"heben","en":"to lift","ru":"поднимать","vi":"nâng","fa":"بالابر","examples":[{"de":"Er kann den schweren Koffer kaum heben.","en":"He can hardly lift the heavy suitcase.","ru":"Он едва может поднять тяжёлый чемодан.","vi":"Anh gần như không thể nhấc nổi chiếc vali nặng nề.","fa":"او به سختی می تواند چمدان سنگین را بلند کند."},{"de":"Bitte hebt die Hand, wenn ihr eine Frage habt.","en":"Please raise your hand if you have a question.","ru":"Пожалуйста, поднимите руку, если у вас есть вопрос.","vi":"Hãy giơ tay nếu bạn có câu hỏi.","fa":"لطفا اگر سوالی دارید دست خود را بالا ببرید."}]},{"word":"das Heer","en":"army","ru":"войско, армия","vi":"quân đội","fa":"the army","examples":[{"de":"Der König stellte ein großes Heer auf.","en":"The king raised a large army.","ru":"Король собрал большое войско.","vi":"Nhà vua đã huy động một đội quân lớn.","fa":"شاه لشکری بزرگ تشکیل داد."},{"de":"Das Heer marschierte tagelang durch das Land.","en":"The army marched through the land for days.","ru":"Войско много дней шло через страну.","vi":"Quân đội hành quân khắp đất nước trong nhiều ngày.","fa":"ارتش روزها در سراسر کشور رژه رفتند."},{"de":"Das feindliche Heer war zahlenmäßig überlegen.","en":"The enemy army was numerically superior.","ru":"Вражеская армия превосходила численно.","vi":"Quân địch vượt trội về số lượng.","fa":"ارتش دشمن از نظر عددی برتر بود."}]},{"word":"das Heft","en":"notebook; exercise book","ru":"тетрадь","vi":"tập sách nhỏ","fa":"جزوه","examples":[{"de":"Jeder Schüler braucht ein Heft für Mathematik.","en":"Every student needs a notebook for math.","ru":"Каждому ученику нужна тетрадь по математике.","vi":"Mỗi học sinh đều cần một cuốn sổ toán.","fa":"هر دانش آموزی به یک دفتر ریاضی نیاز دارد."},{"de":"Sie schreibt die Vokabeln in ihr Heft.","en":"She writes the vocabulary in her notebook.","ru":"Она записывает слова в свою тетрадь.","vi":"Cô ấy viết từ vựng vào sổ tay của mình.","fa":"واژگان را در دفترچه اش می نویسد."}]},{"word":"heim","en":"home(ward) (going home)","ru":"домой","vi":"nhà","fa":"خانه","examples":[{"de":"Nach der Arbeit fahre ich müde heim.","en":"After work I drive home tired.","ru":"После работы я устало еду домой.","vi":"Sau giờ làm việc tôi lái xe về nhà mệt mỏi.","fa":"بعد از کار خسته به خانه می روم."},{"de":"Es wird spät, wir sollten heimgehen.","en":"It's getting late, we should go home.","ru":"Уже поздно, нам стоит пойти домой.","vi":"Cũng muộn rồi, chúng ta nên về nhà thôi.","fa":"داره دیر میشه باید بریم خونه"}]},{"word":"das Heim","en":"home (institution, e.g. residential home)","ru":"дом, приют (учреждение)","vi":"ngôi nhà","fa":"خانه","examples":[{"de":"Die alte Dame lebt jetzt in einem Heim.","en":"The old lady now lives in a residential home.","ru":"Пожилая дама теперь живёт в доме престарелых.","vi":"Bà già hiện đang sống trong một ngôi nhà.","fa":"پیرزن اکنون در یک خانه زندگی می کند."},{"de":"Das Kind wuchs in einem Heim auf.","en":"The child grew up in a children's home.","ru":"Ребёнок вырос в детском доме.","vi":"Đứa trẻ lớn lên trong một gia đình.","fa":"کودک در خانه بزرگ شد."}]},{"word":"die Heimat","en":"homeland","ru":"родина","vi":"quê hương","fa":"وطن","examples":[{"de":"Nach vielen Jahren im Ausland kehrte er in seine Heimat zurück.","en":"After many years abroad, he returned to his homeland.","ru":"После многих лет за границей он вернулся на родину.","vi":"Sau nhiều năm ở nước ngoài, anh trở về quê hương.","fa":"پس از سالها خارج از کشور به وطن بازگشت."},{"de":"Seine Heimat ist ein kleines Dorf in den Bergen.","en":"His homeland is a small village in the mountains.","ru":"Его родина — маленькая деревня в горах.","vi":"Nhà anh là một ngôi làng nhỏ trên núi.","fa":"خانه او روستایی کوچک در کوهستان است."}]},{"word":"heimlich","en":"secret; secretly","ru":"тайный, тайно","vi":"bí mật","fa":"مخفیانه","examples":[{"de":"Sie haben heimlich geheiratet, ohne es jemandem zu sagen.","en":"They got married secretly without telling anyone.","ru":"Они тайно поженились, никому не сказав.","vi":"Họ kết hôn bí mật mà không nói cho ai biết.","fa":"آنها پنهانی ازدواج کردند بدون اینکه به کسی بگویند."},{"de":"Er las heimlich das Tagebuch seiner Schwester.","en":"He secretly read his sister's diary.","ru":"Он тайком читал дневник своей сестры.","vi":"Anh bí mật đọc nhật ký của em gái mình.","fa":"او مخفیانه دفتر خاطرات خواهرش را خواند."}]},{"word":"das Heimweh","en":"homesickness","ru":"тоска по родине","vi":"nỗi nhớ nhà","fa":"دلتنگی","examples":[{"de":"Im ersten Semester im Ausland hatte sie oft Heimweh.","en":"In her first semester abroad she often felt homesick.","ru":"В первом семестре за границей она часто тосковала по родине.","vi":"Trong học kỳ đầu tiên ở nước ngoài, cô thường xuyên nhớ nhà.","fa":"در طول ترم اول تحصیل در خارج از کشور، او اغلب دلتنگ بود."},{"de":"Nach zwei Wochen bekam er starkes Heimweh.","en":"After two weeks he became very homesick.","ru":"Через две недели он сильно затосковал по дому.","vi":"Sau hai tuần, anh trở nên rất nhớ nhà.","fa":"بعد از دو هفته به شدت دلتنگ شد."}]},{"word":"heiraten","en":"to marry","ru":"жениться; выходить замуж","vi":"kết hôn","fa":"ازدواج کن","examples":[{"de":"Meine Schwester heiratet nächsten Sommer.","en":"My sister is getting married next summer.","ru":"Моя сестра выходит замуж следующим летом.","vi":"Em gái tôi sẽ kết hôn vào mùa hè tới.","fa":"خواهرم تابستان آینده ازدواج می کند."},{"de":"Sie haben sich in einer kleinen Kirche geheiratet.","en":"They got married in a small church.","ru":"Они поженились в маленькой церкви.","vi":"Họ kết hôn trong một nhà thờ nhỏ.","fa":"آنها در یک کلیسای کوچک ازدواج کردند."}]},{"word":"heiß","en":"hot","ru":"горячий, жаркий","vi":"nóng bức","fa":"داغ","examples":[{"de":"Vorsicht, der Kaffee ist noch sehr heiß!","en":"Careful, the coffee is still very hot!","ru":"Осторожно, кофе ещё очень горячий!","vi":"Hãy cẩn thận, cà phê vẫn còn rất nóng!","fa":"مراقب باشید، قهوه هنوز خیلی داغ است!"},{"de":"Im August ist es in Spanien sehr heiß.","en":"In August it's very hot in Spain.","ru":"В августе в Испании очень жарко.","vi":"Trời rất nóng ở Tây Ban Nha vào tháng 8.","fa":"در ماه اوت در اسپانیا بسیار گرم است."}]},{"word":"heißen","en":"to be called, named","ru":"зваться, называться","vi":"được gọi là","fa":"تماس گرفت","examples":[{"de":"Wie heißt du?","en":"What's your name?","ru":"Как тебя зовут?","vi":"Tên bạn là gì?","fa":"اسمت چیه؟"},{"de":"Die Straße heißt \"Bahnhofstraße\".","en":"The street is called \"Bahnhofstraße\".","ru":"Улица называется «Банхофштрассе».","vi":"Con phố được gọi là “Bahnhofstraße”.","fa":"این خیابان \"Bahnhofstraße\" نام دارد."}]},{"word":"heizen","en":"to heat","ru":"отапливать","vi":"nhiệt","fa":"گرما","examples":[{"de":"Im Winter heizen wir die Wohnung mit Gas.","en":"In winter we heat the apartment with gas.","ru":"Зимой мы отапливаем квартиру газом.","vi":"Vào mùa đông, chúng tôi sưởi ấm căn hộ bằng gas.","fa":"در زمستان آپارتمان را با گاز گرم می کنیم."},{"de":"Man sollte im Herbst nicht schon zu früh heizen.","en":"You shouldn't start heating too early in autumn.","ru":"Осенью не стоит начинать отопление слишком рано.","vi":"Bạn không nên sưởi ấm quá sớm vào mùa thu.","fa":"در پاییز نباید خیلی زود گرم کنید."}]},{"word":"der Held","en":"hero","ru":"герой","vi":"anh hùng","fa":"قهرمان","examples":[{"de":"Der Feuerwehrmann wurde als Held gefeiert.","en":"The firefighter was celebrated as a hero.","ru":"Пожарного чествовали как героя.","vi":"Người lính cứu hỏa được tôn vinh như một anh hùng.","fa":"از آتش نشان به عنوان یک قهرمان تجلیل شد."},{"de":"In dem Film ist der Held ein einfacher Fischer.","en":"In the movie, the hero is a simple fisherman.","ru":"В фильме герой — простой рыбак.","vi":"Trong phim, anh hùng là một ngư dân giản dị.","fa":"در فیلم، قهرمان یک ماهیگیر ساده است."}]},{"word":"die Heldin","en":"heroine","ru":"героиня","vi":"nữ anh hùng","fa":"قهرمان","examples":[{"de":"Die Heldin des Films rettet die ganze Stadt.","en":"The heroine of the film saves the whole city.","ru":"Героиня фильма спасает весь город.","vi":"Nhân vật nữ chính của phim đã cứu cả thành phố.","fa":"قهرمان فیلم تمام شهر را نجات می دهد."},{"de":"Für viele Kinder ist ihre Mutter eine Heldin.","en":"For many children their mother is a heroine.","ru":"Для многих детей их мать — героиня.","vi":"Đối với nhiều đứa trẻ, mẹ là một anh hùng.","fa":"برای بسیاری از کودکان، مادر آنها یک قهرمان است."},{"de":"Die junge Ärztin wurde nach der Rettung als Heldin gefeiert.","en":"After the rescue the young doctor was celebrated as a heroine.","ru":"После спасения молодую врачиху чествовали как героиню.","vi":"Vị bác sĩ trẻ được tôn vinh như một anh hùng sau cuộc giải cứu.","fa":"دکتر جوان پس از نجات به عنوان یک قهرمان تجلیل شد."}]},{"word":"helfen","en":"to help","ru":"помогать","vi":"giúp đỡ","fa":"کمک کند","examples":[{"de":"Kannst du mir bitte beim Umzug helfen?","en":"Can you help me with the move, please?","ru":"Можешь помочь мне с переездом?","vi":"Bạn có thể vui lòng giúp tôi di chuyển được không?","fa":"میشه لطفا کمکم کنید حرکت کنم؟"},{"de":"Die Nachbarin hilft der alten Frau beim Einkaufen.","en":"The neighbor helps the old woman with shopping.","ru":"Соседка помогает пожилой женщине с покупками.","vi":"Người hàng xóm giúp bà già đi mua sắm.","fa":"همسایه در خرید به پیرزن کمک می کند."}]},{"word":"der Helfer","en":"helper; assistant","ru":"помощник; вспомогательное средство","vi":"người trợ giúp","fa":"کمک کننده","examples":[{"de":"Für das Fest suchen wir noch ein paar Helfer.","en":"We are still looking for a few helpers for the festival.","ru":"Для праздника мы всё ещё ищем несколько помощников.","vi":"Chúng tôi đang tìm kiếm một vài người giúp đỡ cho lễ hội.","fa":"برای جشنواره به دنبال چند یاور هستیم."},{"de":"Die freiwilligen Helfer arbeiten den ganzen Tag.","en":"The volunteer helpers work all day long.","ru":"Добровольные помощники работают весь день.","vi":"Các tình nguyện viên làm việc cả ngày.","fa":"داوطلبان تمام روز کار می کنند."},{"de":"Ohne seine Helfer hätte er das nie geschafft.","en":"Without his helpers he would never have managed it.","ru":"Без своих помощников он бы никогда с этим не справился.","vi":"Anh ấy sẽ không bao giờ có thể làm được điều này nếu không có sự giúp đỡ của anh ấy.","fa":"او بدون یارانش هرگز نمی توانست این کار را انجام دهد."}]},{"word":"hell","en":"bright; light","ru":"светлый","vi":"tươi sáng","fa":"روشن","examples":[{"de":"Das Wohnzimmer ist sehr hell, weil es große Fenster hat.","en":"The living room is very bright because it has large windows.","ru":"Гостиная очень светлая, потому что там большие окна.","vi":"Phòng khách rất sáng sủa vì có cửa sổ lớn.","fa":"اتاق نشیمن به دلیل داشتن پنجره های بزرگ بسیار روشن است."},{"de":"Sie trägt gern helle Farben im Sommer.","en":"She likes to wear light colors in summer.","ru":"Летом она любит носить светлые цвета.","vi":"Cô ấy thích mặc màu sắc tươi sáng vào mùa hè.","fa":"او دوست دارد در تابستان رنگ های روشن بپوشد."}]},{"word":"das Hemd","en":"shirt","ru":"рубашка","vi":"chiếc áo sơ mi","fa":"پیراهن","examples":[{"de":"Er trägt zur Arbeit immer ein weißes Hemd.","en":"He always wears a white shirt to work.","ru":"На работу он всегда носит белую рубашку.","vi":"Anh ấy luôn mặc áo sơ mi trắng đi làm.","fa":"او همیشه یک پیراهن سفید به سر کار می پوشد."},{"de":"Das Hemd muss noch gebügelt werden.","en":"The shirt still needs to be ironed.","ru":"Рубашку ещё нужно погладить.","vi":"Chiếc áo vẫn cần được ủi.","fa":"پیراهن هنوز باید اتو شود."}]},{"word":"das Hend(e)l","en":"chicken (as food, Austrian/Bavarian term)","ru":"курица (австр./баварск.)","vi":"con gà","fa":"مرغ","examples":[{"de":"In Österreich isst man gern ein knuspriges Hendl.","en":"In Austria people like to eat a crispy chicken.","ru":"В Австрии любят есть хрустящую курицу.","vi":"Ở Áo người ta thích ăn gà giòn.","fa":"در اتریش مردم دوست دارند مرغ ترد بخورند."},{"de":"Zum Mittagessen bestellen wir ein halbes Hendl mit Pommes.","en":"For lunch we order half a chicken with fries.","ru":"На обед мы заказываем половину курицы с картошкой фри.","vi":"Bữa trưa chúng tôi gọi nửa con gà với khoai tây chiên.","fa":"برای ناهار نصف مرغ با سیب زمینی سرخ شده سفارش می دهیم."}]},{"word":"das Henderl","en":"(Austrian) roast chicken","ru":"жареная курочка (австр.)","vi":"con gà","fa":"مرغ","examples":[{"de":"In Wien isst man gern ein knuspriges Henderl.","en":"In Vienna people like to eat a crispy roast chicken.","ru":"В Вене любят есть хрустящую жареную курочку.","vi":"Ở Vienna người ta thích ăn gà giòn.","fa":"در وین مردم دوست دارند یک مرغ ترد بخورند."},{"de":"Zum Mittagessen gab es Henderl mit Kartoffelsalat.","en":"For lunch there was roast chicken with potato salad.","ru":"На обед была жареная курочка с картофельным салатом.","vi":"Bữa trưa chúng tôi ăn gà với salad khoai tây.","fa":"برای ناهار مرغ با سالاد سیب زمینی خوردیم."},{"de":"Das Henderl beim Heurigen war besonders lecker.","en":"The roast chicken at the wine tavern was especially tasty.","ru":"Жареная курочка в винной таверне была особенно вкусной.","vi":"Món henderl ở Heuriger đặc biệt ngon.","fa":"هندرل در Heuriger بسیار خوشمزه بود."}]},{"word":"das Hendl","en":"(Austrian/Bavarian) chicken","ru":"курица (австр./бавар.)","vi":"con gà","fa":"مرغ","examples":[{"de":"Auf dem Oktoberfest isst man oft ein halbes Hendl.","en":"At the Oktoberfest people often eat half a chicken.","ru":"На Октоберфесте часто едят половину курицы.","vi":"Tại lễ hội tháng mười bạn thường ăn nửa con gà.","fa":"در Oktoberfest شما اغلب نصف مرغ می خورید."},{"de":"Das Hendl wird über offenem Feuer gegrillt.","en":"The chicken is grilled over an open fire.","ru":"Курицу жарят на открытом огне.","vi":"Gà được nướng trên bếp lửa.","fa":"مرغ را روی آتش باز کبابی می کنند."},{"de":"Ein frisches Hendl schmeckt am besten mit Salat.","en":"A fresh chicken tastes best with salad.","ru":"Свежая курица лучше всего с салатом.","vi":"Thịt gà tươi ngon nhất khi ăn kèm salad.","fa":"مرغ تازه با سالاد بهترین طعم را دارد."}]},{"word":"her","en":"here, toward the speaker (indicates movement)","ru":"сюда","vi":"ở đây","fa":"اینجا","examples":[{"de":"Komm mal her, ich zeige dir etwas!","en":"Come here, I'll show you something!","ru":"Иди сюда, я тебе кое-что покажу!","vi":"Hãy đến đây, tôi sẽ cho bạn thấy một cái gì đó!","fa":"بیا اینجا، یه چیزی بهت نشون میدم!"},{"de":"Woher kommst du?","en":"Where do you come from?","ru":"Откуда ты?","vi":"Bạn đến từ đâu?","fa":"شما از کجا می آیید؟"}]},{"word":"herausfinden","en":"to find out","ru":"выяснять, узнавать","vi":"tìm hiểu","fa":"پیدا کردن","examples":[{"de":"Wir müssen herausfinden, wer die Tür offen gelassen hat.","en":"We need to find out who left the door open.","ru":"Нам нужно выяснить, кто оставил дверь открытой.","vi":"Chúng ta phải tìm ra ai đã để cửa mở.","fa":"باید بفهمیم چه کسی در را باز گذاشته است."},{"de":"Sie hat endlich die Wahrheit herausgefunden.","en":"She finally found out the truth.","ru":"Она наконец узнала правду.","vi":"Cuối cùng cô đã tìm ra sự thật.","fa":"او بالاخره به حقیقت پی برد."}]},{"word":"die Herausforderung","en":"challenge","ru":"вызов, трудная задача","vi":"thử thách","fa":"چالش","examples":[{"de":"Die neue Stelle ist eine große Herausforderung für mich.","en":"The new job is a big challenge for me.","ru":"Новая должность — это большой вызов для меня.","vi":"Vị trí mới là một thách thức lớn đối với tôi.","fa":"موقعیت جدید برای من چالش بزرگی است."},{"de":"Er liebt es, sich neuen Herausforderungen zu stellen.","en":"He loves facing new challenges.","ru":"Он любит принимать новые вызовы.","vi":"Anh ấy thích tham gia những thử thách mới.","fa":"او عاشق چالش های جدید است."}]},{"word":"herb","en":"tart, dry (of taste)","ru":"терпкий, сухой (о вкусе)","vi":"chua chát","fa":"تارت","examples":[{"de":"Dieser Wein ist mir zu herb.","en":"This wine is too dry for me.","ru":"Это вино для меня слишком терпкое.","vi":"Rượu này quá đắng đối với tôi.","fa":"این شراب برای من خیلی تلخ است."},{"de":"Das Bier hat einen herben Geschmack.","en":"The beer has a tart taste.","ru":"У пива терпкий вкус.","vi":"Bia có vị đắng.","fa":"آبجو طعم تلخی دارد."},{"de":"Sie mag den herben Geschmack von schwarzem Kaffee.","en":"She likes the bitter-dry taste of black coffee.","ru":"Ей нравится терпкий вкус чёрного кофе.","vi":"Cô thích vị đắng của cà phê đen.","fa":"او طعم تلخ قهوه سیاه را دوست دارد."}]},{"word":"der Herd","en":"stove; cooker","ru":"плита","vi":"cái bếp","fa":"اجاق گاز","examples":[{"de":"Der Topf steht auf dem Herd.","en":"The pot is on the stove.","ru":"Кастрюля стоит на плите.","vi":"Cái nồi đang ở trên bếp.","fa":"قابلمه روی اجاق است."},{"de":"Vergiss nicht, den Herd auszuschalten!","en":"Don't forget to turn off the stove!","ru":"Не забудь выключить плиту!","vi":"Đừng quên tắt bếp nhé!","fa":"فراموش نکنید که اجاق گاز را خاموش کنید!"}]},{"word":"herein-","en":"prefix meaning \"in(to)\" toward the speaker (e.g. \"hereinkommen\" = to come in)","ru":"приставка со значением «внутрь» (в сторону говорящего), напр. hereinkommen — входить","vi":"trong-","fa":"در-","examples":[{"de":"Bitte komm herein, die Tür ist offen.","en":"Please come in, the door is open.","ru":"Пожалуйста, входи, дверь открыта.","vi":"Mời vào, cửa đang mở.","fa":"لطفا بیا داخل، در باز است."},{"de":"Er bat den Gast, hereinzukommen.","en":"He asked the guest to come in.","ru":"Он попросил гостя войти.","vi":"Anh ta mời khách vào.","fa":"از مهمان خواست داخل شود."}]},{"word":"die Herkunft","en":"origin","ru":"происхождение","vi":"nguồn gốc","fa":"منشاء","examples":[{"de":"Seine Herkunft ist ihm sehr wichtig.","en":"His origin is very important to him.","ru":"Его происхождение очень важно для него.","vi":"Nguồn gốc của anh ấy rất quan trọng đối với anh ấy.","fa":"منشأ او برای او بسیار مهم است."},{"de":"Woher ihre Familie stammt, also ihre Herkunft, ist unbekannt.","en":"Where her family comes from, i.e. her origin, is unknown.","ru":"Откуда родом её семья, то есть её происхождение, неизвестно.","vi":"Gia đình cô ấy đến từ đâu, tức là nguồn gốc của cô ấy, vẫn chưa được biết.","fa":"خانواده او از کجا می آیند، یعنی منشأ او، مشخص نیست."}]},{"word":"das Herkunftsland","en":"country of origin","ru":"страна происхождения","vi":"nước xuất xứ","fa":"کشور مبدا","examples":[{"de":"Auf dem Etikett steht das Herkunftsland der Früchte.","en":"The label shows the country of origin of the fruit.","ru":"На этикетке указана страна происхождения фруктов.","vi":"Nước xuất xứ của trái cây được ghi trên nhãn.","fa":"کشور مبدا میوه روی برچسب ذکر شده است."},{"de":"Viele Migranten besuchen ihr Herkunftsland nur selten.","en":"Many migrants rarely visit their country of origin.","ru":"Многие мигранты навещают страну своего происхождения лишь изредка.","vi":"Nhiều người di cư hiếm khi về thăm quê hương của họ.","fa":"بسیاری از مهاجران به ندرت از کشور مبدا خود دیدن می کنند."},{"de":"Das Herkunftsland des Kaffees ist Kolumbien.","en":"The country of origin of the coffee is Colombia.","ru":"Страна происхождения этого кофе — Колумбия.","vi":"Nước xuất xứ của cà phê là Colombia.","fa":"کشور مبدا قهوه کلمبیا است."}]},{"word":"der Herr","en":"Mr.; gentleman","ru":"господин, мужчина","vi":"ông; quý ông","fa":"آقا","examples":[{"de":"Guten Tag, Herr Müller!","en":"Good day, Mr. Müller!","ru":"Добрый день, господин Мюллер!","vi":"Chào buổi chiều, ông Müller!","fa":"ظهر بخیر آقای مولر!"},{"de":"Ein älterer Herr hat mir den Weg gezeigt.","en":"An elderly gentleman showed me the way.","ru":"Пожилой мужчина показал мне дорогу.","vi":"Một người đàn ông lớn tuổi đã chỉ đường cho tôi.","fa":"یک آقای بزرگتر راه را به من نشان داد."}]},{"word":"herrlich","en":"wonderful; magnificent; glorious","ru":"чудесный, великолепный, восхитительный","vi":"tuyệt vời","fa":"فوق العاده","examples":[{"de":"Wir hatten ein herrliches Wetter im Urlaub.","en":"We had wonderful weather on holiday.","ru":"В отпуске у нас была чудесная погода.","vi":"Chúng tôi đã có thời tiết tuyệt vời trong kỳ nghỉ.","fa":"در تعطیلات هوای فوق العاده ای داشتیم."},{"de":"Von hier oben hat man eine herrliche Aussicht.","en":"From up here you have a magnificent view.","ru":"Отсюда сверху открывается великолепный вид.","vi":"Từ trên đây bạn có một cái nhìn tuyệt vời.","fa":"از این بالا منظره فوق العاده ای دارید."},{"de":"Das Essen war einfach herrlich.","en":"The food was simply wonderful.","ru":"Еда была просто восхитительной.","vi":"Thức ăn đơn giản là tuyệt vời.","fa":"غذا به سادگی فوق العاده بود."}]},{"word":"herstellen","en":"to produce; to manufacture","ru":"производить, изготавливать","vi":"sản xuất","fa":"تولید کنند","examples":[{"de":"Die Firma stellt Möbel aus Holz her.","en":"The company manufactures furniture from wood.","ru":"Компания производит мебель из дерева.","vi":"Công ty sản xuất đồ nội thất từ gỗ.","fa":"این شرکت مبلمان را از چوب می سازد."},{"de":"Diese Autos werden in Deutschland hergestellt.","en":"These cars are manufactured in Germany.","ru":"Эти автомобили производятся в Германии.","vi":"Những chiếc xe này được sản xuất tại Đức.","fa":"این خودروها ساخت آلمان هستند."}]},{"word":"der Hersteller","en":"manufacturer; producer","ru":"производитель, изготовитель","vi":"nhà sản xuất","fa":"سازنده","examples":[{"de":"Der Hersteller gibt zwei Jahre Garantie auf das Gerät.","en":"The manufacturer gives a two-year guarantee on the device.","ru":"Производитель даёт двухлетнюю гарантию на прибор.","vi":"Nhà sản xuất bảo hành hai năm cho thiết bị.","fa":"سازنده دستگاه را دو سال گارانتی می دهد."},{"de":"Bei Problemen sollte man sich an den Hersteller wenden.","en":"If there are problems, you should contact the manufacturer.","ru":"При возникновении проблем стоит обратиться к производителю.","vi":"Nếu bạn có bất kỳ vấn đề gì, bạn nên liên hệ với nhà sản xuất.","fa":"اگر مشکلی دارید، باید با سازنده تماس بگیرید."},{"de":"Dieser Hersteller produziert umweltfreundliche Verpackungen.","en":"This manufacturer produces environmentally friendly packaging.","ru":"Этот производитель выпускает экологичную упаковку.","vi":"Nhà sản xuất này sản xuất bao bì thân thiện với môi trường.","fa":"این سازنده بسته بندی سازگار با محیط زیست تولید می کند."}]},{"word":"die Herstellung","en":"production; manufacturing","ru":"изготовление; производство","vi":"sản xuất","fa":"تولید","examples":[{"de":"Die Herstellung eines Autos dauert viele Stunden.","en":"The production of a car takes many hours.","ru":"Изготовление автомобиля занимает много часов.","vi":"Làm một chiếc ô tô mất nhiều giờ.","fa":"ساخت خودرو ساعت ها طول می کشد."},{"de":"Bei der Herstellung wird auf Qualität geachtet.","en":"Quality is prioritised during production.","ru":"При производстве уделяют внимание качеству.","vi":"Chất lượng được tính đến trong quá trình sản xuất.","fa":"کیفیت در هنگام تولید در نظر گرفته می شود."}]},{"word":"herunter","en":"down (from up there, toward the speaker)","ru":"вниз (сюда)","vi":"xuống","fa":"پایین","examples":[{"de":"Der Ball rollte die Treppe herunter.","en":"The ball rolled down the stairs.","ru":"Мяч скатился по лестнице вниз.","vi":"Quả bóng lăn xuống cầu thang.","fa":"توپ از پله ها پایین آمد."},{"de":"Von hier oben kann man auf die ganze Stadt herunterschauen.","en":"From up here you can look down over the whole city.","ru":"Отсюда сверху можно смотреть вниз на весь город.","vi":"Từ trên đây có thể nhìn xuống toàn bộ thành phố.","fa":"از این بالا می توانید کل شهر را از بالا نگاه کنید."}]},{"word":"herunter-","en":"prefix meaning \"down\" toward the speaker (e.g. \"herunterkommen\" = to come down)","ru":"приставка со значением «вниз» (в сторону говорящего), напр. herunterkommen — спускаться","vi":"xuống-","fa":"پایین -","examples":[{"de":"Komm bitte herunter, das Essen ist fertig!","en":"Please come down, the food is ready!","ru":"Спустись, пожалуйста, еда готова!","vi":"Mời anh xuống, đồ ăn đã sẵn sàng rồi!","fa":"لطفا بیا پایین، غذا آماده است!"},{"de":"Die Katze wollte nicht vom Baum herunterkommen.","en":"The cat didn't want to come down from the tree.","ru":"Кошка не хотела слезать с дерева.","vi":"Con mèo không muốn rời khỏi cây.","fa":"گربه نمی خواست از درخت پایین بیاید."}]},{"word":"herunterfahren","en":"to shut down (a computer); to drive down","ru":"выключать (компьютер); спускаться (на машине)","vi":"tắt","fa":"تعطیل کردن","examples":[{"de":"Bitte fahre den Computer herunter, bevor du gehst.","en":"Please shut down the computer before you leave.","ru":"Пожалуйста, выключи компьютер, прежде чем уйти.","vi":"Hãy tắt máy tính trước khi rời đi.","fa":"لطفا قبل از خروج کامپیوتر را خاموش کنید."},{"de":"Wir sind langsam den steilen Berg heruntergefahren.","en":"We slowly drove down the steep mountain.","ru":"Мы медленно спустились с крутой горы на машине.","vi":"Chúng tôi từ từ đi xuống ngọn núi dốc.","fa":"آرام آرام از کوه شیب دار پایین آمدیم."}]},{"word":"das Herz","en":"heart","ru":"сердце","vi":"trái tim","fa":"قلب","examples":[{"de":"Ihr Herz schlägt vor Aufregung sehr schnell.","en":"Her heart is beating very fast from excitement.","ru":"Её сердце бьётся очень быстро от волнения.","vi":"Tim cô đập rất nhanh vì phấn khích.","fa":"قلبش از هیجان خیلی تند می زند."},{"de":"Er hat ein gutes Herz und hilft gern anderen.","en":"He has a good heart and likes to help others.","ru":"У него доброе сердце, и он любит помогать другим.","vi":"Anh ấy có trái tim nhân hậu và thích giúp đỡ người khác.","fa":"او قلب خوبی دارد و دوست دارد به دیگران کمک کند."}]},{"word":"herzlich","en":"warm, cordial","ru":"сердечный","vi":"nồng nhiệt","fa":"به گرمی","examples":[{"de":"Wir wurden von der Familie sehr herzlich empfangen.","en":"We were welcomed very warmly by the family.","ru":"Семья приняла нас очень сердечно.","vi":"Chúng tôi đã nhận được sự chào đón rất nồng nhiệt từ gia đình.","fa":"ما با استقبال بسیار گرم خانواده مواجه شدیم."},{"de":"Herzlichen Glückwunsch zum Geburtstag!","en":"Warm congratulations on your birthday!","ru":"Сердечно поздравляю с днём рождения!","vi":"Chúc mừng sinh nhật!","fa":"تولدت مبارک!"}]},{"word":"heute","en":"today","ru":"сегодня","vi":"hôm nay","fa":"امروز","examples":[{"de":"Heute scheint endlich wieder die Sonne.","en":"Today the sun is finally shining again.","ru":"Сегодня наконец снова светит солнце.","vi":"Hôm nay mặt trời cuối cùng cũng chiếu sáng trở lại.","fa":"امروز بالاخره خورشید دوباره می درخشد."},{"de":"Ich habe heute keine Zeit für ein Treffen.","en":"I don't have time for a meeting today.","ru":"У меня сегодня нет времени на встречу.","vi":"Hôm nay tôi không có thời gian cho cuộc họp.","fa":"امروز وقت جلسه ندارم"}]},{"word":"hieher","en":"here; to this place (variant of hierher)","ru":"сюда (вариант hierher)","vi":"ở đây","fa":"اینجا","examples":[{"de":"Komm bitte hieher, ich muss dir etwas zeigen.","en":"Please come here, I have to show you something.","ru":"Подойди сюда, мне нужно тебе кое-что показать.","vi":"Hãy đến đây, tôi có thứ này muốn cho bạn xem.","fa":"لطفا بیا اینجا، من چیزی برای نشان دادن به تو دارم."},{"de":"Wie bist du hieher gekommen?","en":"How did you get here?","ru":"Как ты сюда добрался?","vi":"Làm thế nào bạn đến được đây?","fa":"چگونه به اینجا رسیدید؟"},{"de":"Stell die Kiste bitte hieher.","en":"Please put the box here.","ru":"Поставь коробку сюда, пожалуйста.","vi":"Hãy đặt chiếc hộp ở đây.","fa":"لطفا جعبه را اینجا بگذارید."}]},{"word":"hier","en":"here","ru":"здесь","vi":"ở đây","fa":"اینجا","examples":[{"de":"Bitte warte hier auf mich.","en":"Please wait here for me.","ru":"Пожалуйста, подожди меня здесь.","vi":"Xin hãy đợi tôi ở đây.","fa":"لطفا اینجا منتظرم باش"},{"de":"Hier ist es viel ruhiger als in der Stadt.","en":"It's much quieter here than in the city.","ru":"Здесь гораздо тише, чем в городе.","vi":"Ở đây yên tĩnh hơn nhiều so với trong thành phố.","fa":"اینجا خلوت تر از شهر است."}]},{"word":"hierher","en":"(to) here","ru":"сюда","vi":"ở đây","fa":"اینجا","examples":[{"de":"Komm bitte hierher, ich brauche deine Hilfe.","en":"Please come here, I need your help.","ru":"Иди сюда, пожалуйста, мне нужна твоя помощь.","vi":"Hãy đến đây, tôi cần sự giúp đỡ của bạn.","fa":"لطفا بیا اینجا، من به کمک شما نیاز دارم."},{"de":"Wie bist du hierher gekommen?","en":"How did you get here?","ru":"Как ты сюда попал?","vi":"Làm thế nào bạn đến được đây?","fa":"چگونه به اینجا رسیدید؟"}]},{"word":"hiermit","en":"hereby; with this","ru":"настоящим, тем самым, этим","vi":"bằng cách này","fa":"بدین وسیله","examples":[{"de":"Hiermit kündige ich meinen Vertrag.","en":"I hereby terminate my contract.","ru":"Настоящим я расторгаю свой договор.","vi":"Tôi xin chấm dứt hợp đồng của mình.","fa":"بدین وسیله قراردادم را فسخ می کنم."},{"de":"Hiermit möchte ich mich herzlich bedanken.","en":"With this I would like to express my heartfelt thanks.","ru":"Этим я хотел бы выразить свою сердечную благодарность.","vi":"Tôi xin cảm ơn bạn rất nhiều.","fa":"من می خواهم از شما بسیار تشکر کنم."},{"de":"Hiermit bestätigen wir den Eingang Ihrer Zahlung.","en":"We hereby confirm receipt of your payment.","ru":"Настоящим мы подтверждаем получение вашего платежа.","vi":"Chúng tôi xác nhận đã nhận được khoản thanh toán của bạn.","fa":"بدینوسیله دریافت پرداخت شما را تایید می کنیم."}]},{"word":"die Hilfe","en":"help; aid","ru":"помощь","vi":"sự giúp đỡ","fa":"کمک","examples":[{"de":"Vielen Dank für deine Hilfe!","en":"Thank you very much for your help!","ru":"Большое спасибо за твою помощь!","vi":"Cảm ơn sự giúp đỡ của bạn!","fa":"با تشکر از شما برای کمک شما!"},{"de":"Ohne fremde Hilfe hätte ich das nicht geschafft.","en":"I wouldn't have managed it without outside help.","ru":"Без посторонней помощи я бы с этим не справился.","vi":"Tôi sẽ không thể làm được điều này nếu không có sự trợ giúp từ bên ngoài.","fa":"بدون کمک خارجی نمی توانستم این کار را انجام دهم."}]},{"word":"der Himmel","en":"sky; heaven","ru":"небо","vi":"bầu trời","fa":"آسمان","examples":[{"de":"Der Himmel ist heute wolkenlos blau.","en":"The sky is cloudless blue today.","ru":"Сегодня небо безоблачно-голубое.","vi":"Bầu trời hôm nay trong xanh không một gợn mây.","fa":"آسمان امروز آبی بدون ابر است."},{"de":"Abends sieht man am Himmel viele Sterne.","en":"In the evening you can see many stars in the sky.","ru":"Вечером на небе видно много звёзд.","vi":"Vào buổi tối bạn có thể nhìn thấy nhiều ngôi sao trên bầu trời.","fa":"در شب می توانید ستاره های زیادی را در آسمان ببینید."}]},{"word":"der Himmelskörper","en":"celestial body","ru":"небесное тело","vi":"thiên thể","fa":"the celestial body","examples":[{"de":"Sterne, Planeten und Monde sind Himmelskörper.","en":"Stars, planets and moons are celestial bodies.","ru":"Звёзды, планеты и луны — это небесные тела.","vi":"Các ngôi sao, hành tinh và mặt trăng là các thiên thể.","fa":"ستارگان، سیارات و قمرها اجرام آسمانی هستند."},{"de":"Der Astronom beobachtet einen unbekannten Himmelskörper.","en":"The astronomer is observing an unknown celestial body.","ru":"Астроном наблюдает за неизвестным небесным телом.","vi":"Nhà thiên văn học quan sát một thiên thể chưa biết.","fa":"ستاره شناس یک جرم آسمانی ناشناخته را رصد کرد."},{"de":"Jeder Himmelskörper bewegt sich auf seiner eigenen Bahn.","en":"Every celestial body moves on its own path.","ru":"Каждое небесное тело движется по своей собственной орбите.","vi":"Mỗi thiên thể đều di chuyển trên con đường riêng của nó.","fa":"هر جرم آسمانی در مسیر خود حرکت می کند."}]},{"word":"hinfallen","en":"to fall down, to fall over","ru":"падать, упасть (наземь)","vi":"ngã xuống","fa":"سقوط کردن","examples":[{"de":"Pass auf, dass du auf dem Eis nicht hinfällst!","en":"Be careful not to fall over on the ice!","ru":"Осторожно, не упади на льду!","vi":"Hãy cẩn thận để không rơi trên băng!","fa":"مراقب باشید روی یخ نیفتید!"},{"de":"Das Kind ist beim Laufen hingefallen und hat geweint.","en":"The child fell down while running and cried.","ru":"Ребёнок упал на бегу и заплакал.","vi":"Đứa trẻ bị ngã khi đang chạy và khóc.","fa":"کودک در حال دویدن افتاد و گریه کرد."},{"de":"Sie fiel auf der Treppe hin und brach sich den Arm.","en":"She fell on the stairs and broke her arm.","ru":"Она упала на лестнице и сломала руку.","vi":"Cô ngã xuống cầu thang và gãy tay.","fa":"روی پله ها افتاد و دستش شکست."}]},{"word":"hingegen","en":"however; on the other hand","ru":"напротив; зато","vi":"tuy nhiên","fa":"با این حال","examples":[{"de":"Mein Bruder mag Kaffee, ich hingegen trinke lieber Tee.","en":"My brother likes coffee; I, on the other hand, prefer tea.","ru":"Мой брат любит кофе, я же предпочитаю чай.","vi":"Anh trai tôi thích cà phê nhưng tôi thích trà hơn.","fa":"برادر من قهوه دوست دارد، اما من چای را ترجیح می دهم."},{"de":"Der Sommer war heiß, der Winter hingegen sehr mild.","en":"The summer was hot; the winter, however, was very mild.","ru":"Лето было жарким, зима же — очень мягкой.","vi":"Mùa hè rất nóng nhưng mùa đông lại rất ôn hòa.","fa":"تابستان گرم بود، اما زمستان بسیار معتدل بود."}]},{"word":"hinten","en":"at the back; behind","ru":"сзади","vi":"đằng sau","fa":"پشت سر","examples":[{"de":"Die Kinder sitzen hinten im Auto.","en":"The children sit in the back of the car.","ru":"Дети сидят сзади в машине.","vi":"Bọn trẻ ngồi ở phía sau xe.","fa":"بچه ها پشت ماشین می نشینند."},{"de":"Der Ausgang befindet sich ganz hinten im Gebäude.","en":"The exit is at the very back of the building.","ru":"Выход находится в самом конце здания.","vi":"Lối ra nằm ở phía sau tòa nhà.","fa":"خروجی در پشت ساختمان است."}]},{"word":"hinter","en":"behind","ru":"за, позади","vi":"đằng sau","fa":"پشت سر","examples":[{"de":"Der Garten liegt hinter dem Haus.","en":"The garden is behind the house.","ru":"Сад находится за домом.","vi":"Khu vườn nằm phía sau nhà.","fa":"باغ پشت خانه است."},{"de":"Stell das Fahrrad bitte hinter die Garage.","en":"Please put the bicycle behind the garage.","ru":"Поставь, пожалуйста, велосипед за гаражом.","vi":"Vui lòng để xe đạp phía sau gara.","fa":"لطفا دوچرخه را پشت گاراژ بگذارید."},{"de":"Hinter der Schule gibt es einen großen Parkplatz.","en":"There is a large car park behind the school.","ru":"За школой большая парковка.","vi":"Có bãi đậu xe rộng rãi phía sau trường.","fa":"یک پارکینگ بزرگ پشت مدرسه وجود دارد."}]},{"word":"hinterher","en":"afterward; behind, following","ru":"после этого, вслед","vi":"sau đó","fa":"پس از آن","examples":[{"de":"Er lief dem Bus hinterher, aber er war schon weg.","en":"He ran after the bus, but it was already gone.","ru":"Он побежал вслед за автобусом, но тот уже уехал.","vi":"Anh chạy theo chiếc xe buýt nhưng nó đã chạy mất rồi.","fa":"او به دنبال اتوبوس دوید، اما اتوبوس رفته بود."},{"de":"Wir gingen ins Kino und hinterher noch essen.","en":"We went to the cinema and afterward out to eat.","ru":"Мы пошли в кино, а после этого ещё поели.","vi":"Chúng tôi đi xem phim và ăn tối sau đó.","fa":"رفتیم سینما و بعدش شام خوردیم."}]},{"word":"hinter/hinter-","en":"behind","ru":"за, позади","vi":"đằng sau/phía sau-","fa":"پشت / پشت -","examples":[{"de":"Das Auto steht hinter dem Haus.","en":"The car is parked behind the house.","ru":"Машина стоит за домом.","vi":"Ôtô đỗ sau nhà.","fa":"ماشین پشت خانه است."},{"de":"Er versteckte sich hinter dem Baum.","en":"He hid behind the tree.","ru":"Он спрятался за деревом.","vi":"Anh ta trốn đằng sau cái cây.","fa":"پشت درخت پنهان شد."}]},{"word":"hinterlassen","en":"to leave behind","ru":"оставлять (после себя)","vi":"bỏ lại phía sau","fa":"پشت سر گذاشتن","examples":[{"de":"Der Dieb hat keine Spuren hinterlassen.","en":"The thief left no traces behind.","ru":"Вор не оставил никаких следов.","vi":"Tên trộm không để lại dấu vết.","fa":"دزد اثری از خود برجای نگذاشت."},{"de":"Sie hat mir eine Nachricht auf dem Anrufbeantworter hinterlassen.","en":"She left me a message on the answering machine.","ru":"Она оставила мне сообщение на автоответчике.","vi":"Cô ấy để lại cho tôi một tin nhắn trên máy trả lời tự động.","fa":"روی منشی تلفنی برای من پیام گذاشت."}]},{"word":"hinweisen","en":"to point out","ru":"указывать (на что-либо)","vi":"chỉ ra","fa":"اشاره کند","examples":[{"de":"Der Lehrer weist die Schüler auf ihre Fehler hin.","en":"The teacher points out their mistakes to the students.","ru":"Учитель указывает ученикам на их ошибки.","vi":"Giáo viên chỉ ra những lỗi sai của học sinh.","fa":"معلم به اشتباهات دانش آموزان اشاره می کند."},{"de":"Ich möchte darauf hinweisen, dass die Frist morgen endet.","en":"I would like to point out that the deadline ends tomorrow.","ru":"Хочу указать на то, что срок истекает завтра.","vi":"Tôi muốn chỉ ra rằng thời hạn sẽ kết thúc vào ngày mai.","fa":"لازم به ذکر است که این مهلت فردا به پایان می رسد."}]},{"word":"historisch","en":"historical","ru":"исторический","vi":"lịch sử","fa":"تاریخی","examples":[{"de":"Die Altstadt ist ein historisches Zentrum der Stadt.","en":"The old town is a historical center of the city.","ru":"Старый город — исторический центр города.","vi":"Phố cổ là một trung tâm lịch sử của thành phố.","fa":"شهر قدیمی مرکز تاریخی شهر است."},{"de":"Das Museum zeigt historische Dokumente aus dem 19. Jahrhundert.","en":"The museum shows historical documents from the 19th century.","ru":"Музей демонстрирует исторические документы XIX века.","vi":"Bảo tàng trưng bày các tài liệu lịch sử từ thế kỷ 19.","fa":"در این موزه اسناد تاریخی مربوط به قرن نوزدهم به نمایش گذاشته شده است."}]},{"word":"die Hitze","en":"heat","ru":"жара","vi":"cái nóng","fa":"گرما","examples":[{"de":"Bei dieser Hitze kann man kaum draußen arbeiten.","en":"In this heat you can hardly work outside.","ru":"В такую жару почти невозможно работать на улице.","vi":"Hầu như không thể làm việc ngoài trời trong thời tiết nắng nóng này.","fa":"در این گرما کار کردن در بیرون تقریبا غیرممکن است."},{"de":"Die Hitze im Sommer war dieses Jahr besonders stark.","en":"The heat in summer was especially strong this year.","ru":"Летняя жара в этом году была особенно сильной.","vi":"Cái nóng vào mùa hè năm nay đặc biệt gay gắt.","fa":"گرمای تابستان امسال به ویژه شدید بود."}]},{"word":"die Hitzewelle","en":"heatwave","ru":"волна жары, аномальная жара","vi":"sóng nhiệt","fa":"the heat wave","examples":[{"de":"Während der Hitzewelle wurden über vierzig Grad gemessen.","en":"During the heatwave temperatures over forty degrees were recorded.","ru":"Во время волны жары зафиксировали больше сорока градусов.","vi":"Trong đợt nắng nóng, nhiệt độ vượt quá bốn mươi độ.","fa":"در طول موج گرما، دما از چهل درجه گذشت."},{"de":"Bei der Hitzewelle blieben viele Menschen lieber zu Hause.","en":"During the heatwave many people preferred to stay at home.","ru":"Во время жары многие люди предпочитали оставаться дома.","vi":"Trong đợt nắng nóng, nhiều người thích ở nhà hơn.","fa":"در طول موج گرما، بسیاری از مردم ترجیح دادند در خانه بمانند."},{"de":"Die Hitzewelle dauerte fast zwei Wochen lang an.","en":"The heatwave lasted almost two weeks.","ru":"Волна жары длилась почти две недели.","vi":"Đợt nắng nóng kéo dài gần hai tuần.","fa":"موج گرما تقریباً دو هفته ادامه داشت."}]},{"word":"das Hobby","en":"hobby","ru":"хобби","vi":"sở thích","fa":"سرگرمی","examples":[{"de":"Mein liebstes Hobby ist Fotografieren.","en":"My favorite hobby is photography.","ru":"Моё любимое хобби — фотография.","vi":"Sở thích yêu thích của tôi là chụp ảnh.","fa":"سرگرمی مورد علاقه من عکاسی است."},{"de":"Welche Hobbys hast du in deiner Freizeit?","en":"What hobbies do you have in your free time?","ru":"Какие у тебя хобби в свободное время?","vi":"Bạn có sở thích gì trong thời gian rảnh?","fa":"در اوقات فراغت چه سرگرمی هایی دارید؟"}]},{"word":"hoch","en":"high","ru":"высокий","vi":"cao","fa":"بالا","examples":[{"de":"Der Berg ist über zweitausend Meter hoch.","en":"The mountain is over two thousand meters high.","ru":"Гора высотой более двух тысяч метров.","vi":"Ngọn núi cao hơn hai nghìn mét.","fa":"ارتفاع این کوه بیش از دو هزار متر است."},{"de":"Die Mieten in der Stadt sind sehr hoch.","en":"The rents in the city are very high.","ru":"Арендная плата в городе очень высокая.","vi":"Giá thuê trong thành phố rất cao.","fa":"اجاره در شهر بسیار بالاست."}]},{"word":"das Hochhaus","en":"high-rise building; tower block","ru":"высотное здание, многоэтажка","vi":"tòa nhà chọc trời","fa":"آسمان خراش","examples":[{"de":"Sie wohnt im zehnten Stock eines Hochhauses.","en":"She lives on the tenth floor of a high-rise building.","ru":"Она живёт на десятом этаже высотного здания.","vi":"Cô sống trên tầng mười của một tòa nhà cao tầng.","fa":"او در طبقه دهم یک ساختمان بلند زندگی می کند."},{"de":"Im Zentrum stehen viele moderne Hochhäuser.","en":"There are many modern high-rise buildings in the centre.","ru":"В центре стоит много современных высотных зданий.","vi":"Có rất nhiều tòa nhà cao tầng hiện đại ở trung tâm.","fa":"بسیاری از ساختمان های مرتفع مدرن در مرکز وجود دارد."},{"de":"Vom Hochhaus aus hat man einen tollen Blick über die Stadt.","en":"From the high-rise you have a great view over the city.","ru":"С высотки открывается прекрасный вид на город.","vi":"Từ tầng cao bạn có một cái nhìn tuyệt vời về thành phố.","fa":"از بلند مرتبه منظره ای عالی از شهر دارید."}]},{"word":"hochladen","en":"to upload","ru":"загружать (в интернет)","vi":"tải lên","fa":"آپلود کنید","examples":[{"de":"Ich muss die Fotos noch auf die Webseite hochladen.","en":"I still need to upload the photos to the website.","ru":"Мне ещё нужно загрузить фотографии на сайт.","vi":"Tôi vẫn phải tải ảnh lên trang web.","fa":"من هنوز باید عکس ها را در سایت آپلود کنم."},{"de":"Er hat das Video gestern auf YouTube hochgeladen.","en":"He uploaded the video to YouTube yesterday.","ru":"Вчера он загрузил видео на YouTube.","vi":"Anh ấy đã tải video lên YouTube ngày hôm qua.","fa":"او دیروز این ویدئو را در یوتیوب آپلود کرد."}]},{"word":"höchstens","en":"at most","ru":"самое большее, максимум","vi":"nhiều nhất","fa":"حداکثر","examples":[{"de":"Die Fahrt dauert höchstens eine Stunde.","en":"The trip takes at most one hour.","ru":"Поездка занимает максимум один час.","vi":"Cuộc hành trình mất tối đa một giờ.","fa":"سفر حداکثر یک ساعت طول می کشد."},{"de":"Ich kann höchstens zwei Tage bleiben.","en":"I can stay for at most two days.","ru":"Я могу остаться самое большее на два дня.","vi":"Tôi chỉ có thể ở lại nhiều nhất là hai ngày.","fa":"حداکثر دو روز میتونم بمونم"}]},{"word":"die Hochzeit","en":"wedding","ru":"свадьба","vi":"đám cưới","fa":"عروسی","examples":[{"de":"Meine Schwester heiratet im Sommer, die Hochzeit findet im Garten statt.","en":"My sister is getting married in summer, the wedding takes place in the garden.","ru":"Моя сестра выходит замуж летом, свадьба состоится в саду.","vi":"Chị tôi sắp kết hôn vào mùa hè, đám cưới sẽ diễn ra ngoài vườn.","fa":"خواهرم در تابستان عروسی می کند، عروسی در باغ برگزار می شود."},{"de":"Wir waren letztes Wochenende auf einer Hochzeit eingeladen.","en":"We were invited to a wedding last weekend.","ru":"На прошлых выходных нас пригласили на свадьбу.","vi":"Chúng tôi được mời đến dự một đám cưới vào cuối tuần trước.","fa":"آخر هفته پیش به عروسی دعوت شدیم."}]},{"word":"der Hof","en":"courtyard; farm","ru":"двор; ферма","vi":"sân","fa":"حیاط","examples":[{"de":"Die Kinder spielen im Hof des Hauses.","en":"The children are playing in the courtyard of the house.","ru":"Дети играют во дворе дома.","vi":"Bọn trẻ chơi đùa trong sân nhà.","fa":"بچه ها در حیاط خانه بازی می کنند."},{"de":"Meine Großeltern haben einen Hof mit vielen Tieren.","en":"My grandparents have a farm with many animals.","ru":"У моих бабушки и дедушки ферма со множеством животных.","vi":"Ông bà tôi có một trang trại với rất nhiều động vật.","fa":"پدربزرگ و مادربزرگ من مزرعه ای با حیوانات زیادی دارند."}]},{"word":"hoffen","en":"to hope","ru":"надеяться","vi":"hy vọng","fa":"امید","examples":[{"de":"Ich hoffe, dass das Wetter morgen besser wird.","en":"I hope the weather will be better tomorrow.","ru":"Я надеюсь, что завтра погода будет лучше.","vi":"Tôi hy vọng ngày mai thời tiết sẽ tốt hơn.","fa":"امیدوارم فردا هوا بهتر بشه"},{"de":"Wir hoffen auf ein gutes Ergebnis.","en":"We are hoping for a good result.","ru":"Мы надеемся на хороший результат.","vi":"Chúng tôi hy vọng cho một kết quả tốt.","fa":"امیدواریم نتیجه خوبی بگیریم."}]},{"word":"die Hoffnung","en":"hope","ru":"надежда","vi":"hy vọng","fa":"امید","examples":[{"de":"Wir geben die Hoffnung nicht auf.","en":"We're not giving up hope.","ru":"Мы не теряем надежды.","vi":"Chúng tôi không từ bỏ hy vọng.","fa":"ما امید خود را از دست نمی دهیم"},{"de":"Es gibt immer noch Hoffnung.","en":"There's still hope.","ru":"Надежда ещё есть.","vi":"Vẫn còn hy vọng.","fa":"هنوز امیدی هست."},{"de":"Die Patienten setzen ihre ganze Hoffnung auf das neue Medikament.","en":"The patients are pinning all their hope on the new medicine.","ru":"Пациенты возлагают всю свою надежду на новое лекарство.","vi":"Bệnh nhân đang đặt hết hy vọng vào loại thuốc mới.","fa":"بیماران تمام امید خود را به داروی جدید بسته اند."}]},{"word":"höflich","en":"polite","ru":"вежливый","vi":"lịch sự","fa":"مودب","examples":[{"de":"Der Kellner war sehr höflich zu uns.","en":"The waiter was very polite to us.","ru":"Официант был очень вежлив с нами.","vi":"Người phục vụ rất lịch sự với chúng tôi.","fa":"گارسون با ما خیلی مودب بود."},{"de":"Man sollte immer höflich grüßen.","en":"One should always greet politely.","ru":"Всегда нужно вежливо здороваться.","vi":"Bạn nên luôn chào hỏi một cách lịch sự.","fa":"همیشه باید مودبانه سلام کرد."}]},{"word":"die Höflichkeit","en":"politeness","ru":"вежливость","vi":"sự lịch sự","fa":"ادب","examples":[{"de":"Aus Höflichkeit hat er das Geschenk angenommen.","en":"Out of politeness he accepted the gift.","ru":"Из вежливости он принял подарок.","vi":"Anh ấy nhận món quà một cách lịch sự.","fa":"او از روی ادب این هدیه را پذیرفت."},{"de":"Höflichkeit kostet nichts und öffnet viele Türen.","en":"Politeness costs nothing and opens many doors.","ru":"Вежливость ничего не стоит и открывает многие двери.","vi":"Sự lịch sự không tốn kém gì và mở ra nhiều cánh cửa.","fa":"ادب هیچ هزینه ای ندارد و درهای زیادی را باز می کند."}]},{"word":"die Höhe","en":"height","ru":"высота","vi":"chiều cao","fa":"ارتفاع","examples":[{"de":"Das Flugzeug fliegt in einer Höhe von zehntausend Metern.","en":"The plane is flying at a height of ten thousand meters.","ru":"Самолёт летит на высоте десяти тысяч метров.","vi":"Máy bay bay ở độ cao mười nghìn mét.","fa":"این هواپیما در ارتفاع ده هزار متری پرواز می کند."},{"de":"Die Höhe des Turms beträgt fünfzig Meter.","en":"The height of the tower is fifty meters.","ru":"Высота башни составляет пятьдесят метров.","vi":"Chiều cao của tháp là năm mươi mét.","fa":"ارتفاع برج پنجاه متر است."}]},{"word":"holen","en":"to fetch, to get","ru":"принести, забрать","vi":"nhận được","fa":"دریافت کنید","examples":[{"de":"Kannst du bitte Brot vom Bäcker holen?","en":"Can you please get bread from the bakery?","ru":"Можешь, пожалуйста, принести хлеб из пекарни?","vi":"Bạn có thể vui lòng lấy bánh mì từ tiệm bánh được không?","fa":"میشه لطفا از نانوایی نان تهیه کنید؟"},{"de":"Er holt seine Tochter von der Schule.","en":"He picks up his daughter from school.","ru":"Он забирает свою дочь из школы.","vi":"Anh đón con gái từ trường.","fa":"دخترش را از مدرسه می گیرد."}]},{"word":"das Holz","en":"wood","ru":"дерево, древесина","vi":"gỗ","fa":"چوب","examples":[{"de":"Der Tisch ist aus Holz gemacht.","en":"The table is made of wood.","ru":"Стол сделан из дерева.","vi":"Chiếc bàn được làm bằng gỗ.","fa":"میز از چوب ساخته شده است."},{"de":"Im Winter sammeln wir Holz für den Ofen.","en":"In winter we collect wood for the stove.","ru":"Зимой мы собираем дрова для печи.","vi":"Vào mùa đông, chúng tôi thu thập củi để đốt lò.","fa":"در زمستان برای اجاق گاز چوب جمع می کنیم."}]},{"word":"der Honig","en":"honey","ru":"мёд","vi":"mật ong","fa":"عسل","examples":[{"de":"Ich esse morgens gern Honig auf dem Brot.","en":"In the morning I like to eat honey on bread.","ru":"По утрам я люблю есть мёд на хлебе.","vi":"Tôi thích ăn mật ong trên bánh mì vào buổi sáng.","fa":"من دوست دارم صبح روی نان عسل بخورم."},{"de":"Der Honig aus dieser Region schmeckt besonders gut.","en":"The honey from this region tastes especially good.","ru":"Мёд из этого региона особенно вкусный.","vi":"Mật ong từ vùng này có vị đặc biệt ngon.","fa":"عسل این منطقه طعم و مزه خاصی دارد."}]},{"word":"das Honorar","en":"fee","ru":"гонорар","vi":"lệ phí","fa":"هزینه","examples":[{"de":"Für den Vortrag bekommt sie ein hohes Honorar.","en":"She gets a high fee for the lecture.","ru":"За лекцию она получает высокий гонорар.","vi":"Cô ấy nhận được một khoản phí cao cho bài giảng.","fa":"او برای سخنرانی هزینه بالایی دریافت می کند."},{"de":"Das Honorar wird nach Abschluss der Arbeit überwiesen.","en":"The fee will be transferred after the work is completed.","ru":"Гонорар будет перечислен после завершения работы.","vi":"Phí sẽ được chuyển sau khi công việc hoàn thành.","fa":"هزینه پس از اتمام کار واریز خواهد شد."},{"de":"Als Freiberufler muss man sein Honorar selbst verhandeln.","en":"As a freelancer you have to negotiate your fee yourself.","ru":"Работая на себя, гонорар приходится оговаривать самому.","vi":"Là một freelancer, bạn phải tự thương lượng mức phí của mình.","fa":"به عنوان یک فریلنسر، باید در مورد هزینه خود مذاکره کنید."}]},{"word":"hören","en":"to hear, to listen","ru":"слышать, слушать","vi":"nghe thấy","fa":"بشنو","examples":[{"de":"Ich höre gern Musik, wenn ich lerne.","en":"I like listening to music while I study.","ru":"Я люблю слушать музыку, когда учусь.","vi":"Tôi thích nghe nhạc khi học.","fa":"وقتی درس می خوانم دوست دارم موسیقی گوش کنم."},{"de":"Hast du die Nachrichten gehört?","en":"Did you hear the news?","ru":"Ты слышал новости?","vi":"Bạn đã nghe tin tức chưa?","fa":"آیا خبر را شنیده اید؟"}]},{"word":"der Hörer","en":"listener; receiver (telephone)","ru":"слушатель; телефонная трубка","vi":"người nghe","fa":"شنونده","examples":[{"de":"Die Sendung hat jeden Abend tausende treue Hörer.","en":"The programme has thousands of loyal listeners every evening.","ru":"У передачи каждый вечер тысячи преданных слушателей.","vi":"Chương trình có hàng nghìn khán giả trung thành mỗi tối.","fa":"این برنامه هر شب هزاران شنونده وفادار دارد."},{"de":"Er legte den Hörer auf, ohne sich zu verabschieden.","en":"He put down the receiver without saying goodbye.","ru":"Он положил трубку, не попрощавшись.","vi":"Anh cúp máy mà không nói lời tạm biệt.","fa":"بدون خداحافظی تلفن را قطع کرد."},{"de":"Ein Hörer rief in der Radiosendung an.","en":"A listener phoned in to the radio show.","ru":"Слушатель позвонил в радиопередачу.","vi":"Một thính giả gọi vào chương trình radio.","fa":"شنونده ای به برنامه رادیویی زنگ زد."}]},{"word":"die Hörerin","en":"listener (female)","ru":"слушательница","vi":"người nghe","fa":"شنونده","examples":[{"de":"Eine Hörerin stellte dem Experten eine kluge Frage.","en":"A listener asked the expert a clever question.","ru":"Слушательница задала эксперту умный вопрос.","vi":"Một thính giả đã hỏi chuyên gia một câu hỏi thông minh.","fa":"شنونده ای از کارشناس سوال زیرکانه ای پرسید."},{"de":"Die Hörerin gewann den Wettbewerb im Radio.","en":"The listener won the competition on the radio.","ru":"Слушательница выиграла конкурс на радио.","vi":"Người nghe đã giành chiến thắng trong cuộc thi phát thanh.","fa":"شنونده در مسابقه رادیویی برنده شد."},{"de":"Als treue Hörerin schreibt sie dem Sender oft Briefe.","en":"As a loyal listener she often writes letters to the station.","ru":"Как преданная слушательница она часто пишет письма на радиостанцию.","vi":"Là một thính giả trung thành, cô thường xuyên viết thư cho đài.","fa":"به عنوان یک شنونده وفادار، او اغلب برای ایستگاه نامه می نویسد."}]},{"word":"der Horizont","en":"horizon","ru":"горизонт; кругозор","vi":"đường chân trời","fa":"افق","examples":[{"de":"Die Sonne verschwand langsam hinter dem Horizont.","en":"The sun slowly disappeared behind the horizon.","ru":"Солнце медленно скрылось за горизонтом.","vi":"Mặt trời dần biến mất sau đường chân trời.","fa":"خورشید کم کم پشت افق ناپدید شد."},{"de":"Am Horizont konnten wir die Berge erkennen.","en":"On the horizon we could make out the mountains.","ru":"На горизонте мы могли различить горы.","vi":"Chúng tôi có thể nhìn thấy những ngọn núi ở phía chân trời.","fa":"می توانستیم کوه ها را در افق ببینیم."},{"de":"Ein Schiff erschien langsam am Horizont.","en":"A ship slowly appeared on the horizon.","ru":"На горизонте медленно появился корабль.","vi":"Một con tàu từ từ xuất hiện ở phía chân trời.","fa":"یک کشتی به آرامی در افق ظاهر شد."}]},{"word":"die Hose","en":"trousers, pants","ru":"брюки","vi":"cái quần","fa":"شلوار","examples":[{"de":"Die Hose ist mir zu eng geworden.","en":"The trousers have become too tight for me.","ru":"Брюки стали мне тесны.","vi":"Chiếc quần đã trở nên quá chật đối với tôi.","fa":"شلوارم خیلی تنگ شده."},{"de":"Er trägt heute eine blaue Hose.","en":"He is wearing blue trousers today.","ru":"Сегодня он в синих брюках.","vi":"Hôm nay anh ấy mặc quần xanh.","fa":"او امروز شلوار آبی پوشیده است."}]},{"word":"das Hostel","en":"hostel","ru":"хостел","vi":"ký túc xá","fa":"خوابگاه","examples":[{"de":"Wir haben in einem günstigen Hostel im Stadtzentrum übernachtet.","en":"We stayed overnight in a cheap hostel in the city centre.","ru":"Мы переночевали в недорогом хостеле в центре города.","vi":"Chúng tôi ở trong một nhà nghỉ giá rẻ ở trung tâm thành phố.","fa":"ما در یک هاستل ارزان در مرکز شهر اقامت کردیم."},{"de":"Das Hostel bietet sowohl Schlafsäle als auch Einzelzimmer an.","en":"The hostel offers both dormitories and single rooms.","ru":"Хостел предлагает как общие спальни, так и одноместные номера.","vi":"Nhà trọ cung cấp cả phòng ngủ tập thể và phòng đơn.","fa":"این هاستل هم خوابگاه و هم اتاق های یک نفره دارد."},{"de":"Im Hostel haben wir viele junge Reisende kennengelernt.","en":"At the hostel we met lots of young travellers.","ru":"В хостеле мы познакомились со многими молодыми путешественниками.","vi":"Chúng tôi đã gặp nhiều du khách trẻ trong ký túc xá.","fa":"در هاستل با مسافران جوان زیادی آشنا شدیم."}]},{"word":"das Hotel","en":"hotel","ru":"гостиница","vi":"khách sạn","fa":"هتل","examples":[{"de":"Wir übernachten drei Nächte in einem kleinen Hotel.","en":"We are staying three nights in a small hotel.","ru":"Мы ночуем три ночи в небольшой гостинице.","vi":"Chúng tôi ở trong một khách sạn nhỏ trong ba đêm.","fa":"سه شب در هتل کوچکی می مانیم."},{"de":"Das Hotel liegt direkt am Meer.","en":"The hotel is located right by the sea.","ru":"Гостиница находится прямо у моря.","vi":"Khách sạn nằm ngay cạnh biển.","fa":"هتل مستقیماً در کنار دریا واقع شده است."}]},{"word":"die Hotelbeschreibung","en":"hotel description","ru":"описание отеля","vi":"mô tả khách sạn","fa":"توضیحات هتل","examples":[{"de":"Laut der Hotelbeschreibung gibt es einen Pool auf dem Dach.","en":"According to the hotel description there is a pool on the roof.","ru":"Согласно описанию отеля на крыше есть бассейн.","vi":"Theo mô tả của khách sạn có hồ bơi trên sân thượng.","fa":"طبق توضیحات هتل یک استخر روی پشت بام وجود دارد."},{"de":"Die Hotelbeschreibung auf der Webseite war leider ungenau.","en":"The hotel description on the website was unfortunately inaccurate.","ru":"Описание отеля на сайте было, к сожалению, неточным.","vi":"Thật không may, mô tả khách sạn trên trang web không chính xác.","fa":"متأسفانه توضیحات هتل در وب سایت نادرست بود."},{"de":"Lies bitte die Hotelbeschreibung, bevor du buchst.","en":"Please read the hotel description before you book.","ru":"Прочитай, пожалуйста, описание отеля, прежде чем бронировать.","vi":"Vui lòng đọc mô tả khách sạn trước khi đặt phòng.","fa":"لطفا قبل از رزرو، توضیحات هتل را بخوانید."}]},{"word":"hübsch","en":"pretty","ru":"хорошенький, симпатичный","vi":"xinh đẹp","fa":"زیبا","examples":[{"de":"Sie trägt ein hübsches Kleid.","en":"She is wearing a pretty dress.","ru":"На ней симпатичное платье.","vi":"Cô ấy đang mặc một chiếc váy đẹp.","fa":"او یک لباس زیبا پوشیده است."},{"de":"Das ist ein hübsches kleines Dorf.","en":"That is a pretty little village.","ru":"Это симпатичная маленькая деревня.","vi":"Đây là một ngôi làng nhỏ xinh.","fa":"این یک روستای کوچک زیبا است."}]},{"word":"der Hügel","en":"hill","ru":"холм","vi":"ngọn đồi","fa":"تپه","examples":[{"de":"Von diesem Hügel hat man einen tollen Blick auf die Stadt.","en":"From this hill you have a great view of the city.","ru":"С этого холма открывается прекрасный вид на город.","vi":"Từ ngọn đồi này bạn có một cái nhìn tuyệt vời về thành phố.","fa":"از این تپه منظره ای عالی از شهر دارید."},{"de":"Wir sind auf den Hügel gewandert.","en":"We hiked up the hill.","ru":"Мы поднялись пешком на холм.","vi":"Chúng tôi đi bộ lên đồi.","fa":"از تپه بالا رفتیم."}]},{"word":"das Hühnchen","en":"chicken (the meat/small hen)","ru":"курочка (мясо / небольшая курица)","vi":"con gà","fa":"مرغ","examples":[{"de":"Zum Mittagessen gibt es gebratenes Hühnchen mit Reis.","en":"For lunch there is roast chicken with rice.","ru":"На обед жареная курочка с рисом.","vi":"Bữa trưa chúng tôi ăn gà rán với cơm.","fa":"برای ناهار مرغ سرخ شده با برنج داریم."},{"de":"Sie mag Hühnchen lieber als Rindfleisch.","en":"She prefers chicken to beef.","ru":"Курочку она предпочитает говядине.","vi":"Cô ấy thích thịt gà hơn thịt bò.","fa":"او مرغ را بیشتر از گوشت گاو دوست دارد."},{"de":"Das Hühnchen muss noch zehn Minuten im Ofen bleiben.","en":"The chicken needs to stay in the oven for ten more minutes.","ru":"Курочке нужно побыть в духовке ещё десять минут.","vi":"Con gà cần ở trong lò thêm mười phút nữa.","fa":"مرغ باید ده دقیقه دیگر در فر بماند."}]},{"word":"der Humor","en":"humor","ru":"юмор","vi":"sự hài hước","fa":"طنز","examples":[{"de":"Er hat einen guten Sinn für Humor.","en":"He has a good sense of humor.","ru":"У него хорошее чувство юмора.","vi":"Anh ấy có khiếu hài hước.","fa":"او حس شوخ طبعی خوبی دارد."},{"de":"Ohne Humor wäre das Leben langweilig.","en":"Without humor life would be boring.","ru":"Без юмора жизнь была бы скучной.","vi":"Nếu không có sự hài hước, cuộc sống sẽ nhàm chán.","fa":"بدون طنز، زندگی خسته کننده خواهد بود."}]},{"word":"der Hunger","en":"hunger","ru":"голод","vi":"cơn đói","fa":"گرسنگی","examples":[{"de":"Ich habe großen Hunger, lass uns essen gehen.","en":"I'm very hungry, let's go eat.","ru":"Я очень голоден, пойдём поедим.","vi":"Tôi đói quá, chúng ta đi ăn thôi.","fa":"من خیلی گرسنه ام، بریم غذا بخوریم."},{"de":"In manchen Ländern leiden viele Menschen unter Hunger.","en":"In some countries many people suffer from hunger.","ru":"В некоторых странах многие люди страдают от голода.","vi":"Ở một số nước nhiều người bị đói.","fa":"در برخی کشورها بسیاری از مردم از گرسنگی رنج می برند."}]},{"word":"hupen","en":"to honk","ru":"сигналить (клаксоном)","vi":"bấm còi","fa":"بوق زدن","examples":[{"de":"Der Fahrer hupte, weil die Ampel schon grün war.","en":"The driver honked because the light was already green.","ru":"Водитель посигналил, потому что светофор уже был зелёным.","vi":"Người lái xe bấm còi vì đèn giao thông đã xanh.","fa":"راننده بوق زد چون چراغ راهنما از قبل سبز شده بود."},{"de":"Man darf in der Stadt nicht ohne Grund hupen.","en":"You are not allowed to honk in the city without reason.","ru":"В городе нельзя сигналить без причины.","vi":"Bạn không thể bấm còi trong thành phố mà không có lý do.","fa":"بدون دلیل نمی توان در شهر بوق زد."}]},{"word":"husten","en":"to cough","ru":"кашлять","vi":"ho","fa":"سرفه","examples":[{"de":"Er hustet schon seit einer Woche.","en":"He has been coughing for a week already.","ru":"Он кашляет уже неделю.","vi":"Anh ấy đã ho được một tuần rồi.","fa":"او یک هفته است که سرفه می کند."},{"de":"Bitte halte dir die Hand vor den Mund, wenn du hustest.","en":"Please cover your mouth with your hand when you cough.","ru":"Пожалуйста, прикрывай рот рукой, когда кашляешь.","vi":"Hãy đưa tay lên miệng khi ho.","fa":"لطفا هنگام سرفه دست خود را روی دهان خود بگذارید."}]},{"word":"der Hut","en":"hat","ru":"шляпа","vi":"cái mũ","fa":"کلاه","examples":[{"de":"Sie trägt im Sommer immer einen Hut.","en":"She always wears a hat in summer.","ru":"Летом она всегда носит шляпу.","vi":"Cô ấy luôn đội mũ vào mùa hè.","fa":"او همیشه در تابستان کلاه سر می گذارد."},{"de":"Der alte Mann nahm seinen Hut ab und grüßte.","en":"The old man took off his hat and greeted us.","ru":"Старик снял шляпу и поздоровался.","vi":"Ông già bỏ mũ ra chào.","fa":"پیرمرد کلاهش را برداشت و سلام کرد."}]},{"word":"die Hütte","en":"hut, cabin","ru":"хижина","vi":"túp lều","fa":"کلبه","examples":[{"de":"Wir haben die Nacht in einer Berghütte verbracht.","en":"We spent the night in a mountain cabin.","ru":"Мы провели ночь в горной хижине.","vi":"Chúng tôi qua đêm trong một túp lều trên núi.","fa":"شب را در یک کلبه کوهستانی گذراندیم."},{"de":"Die kleine Hütte im Wald gehört meinem Onkel.","en":"The small hut in the forest belongs to my uncle.","ru":"Маленькая хижина в лесу принадлежит моему дяде.","vi":"Căn nhà gỗ nhỏ trong rừng thuộc về chú tôi.","fa":"کلبه کوچک جنگل متعلق به عمویم است."}]},{"word":"Ich bin dagegen","en":"I'm against it (rejecting)","ru":"Я против (отказ)","vi":"Tôi phản đối nó","fa":"من مخالفم","examples":[{"de":"Ich bin dagegen, das ist zu riskant.","en":"I'm against it, that's too risky.","ru":"Я против, это слишком рискованно.","vi":"Tôi phản đối, nó quá mạo hiểm.","fa":"من مخالفم، خیلی ریسک داره."}]},{"word":"Ich bin davon überzeugt, dass …","en":"I'm convinced that … (strong opinion)","ru":"Я убеждён, что … (твёрдое мнение)","vi":"Tôi tin chắc rằng…","fa":"من متقاعد شده ام که…","examples":[{"de":"Ich bin davon überzeugt, dass Sport gesund ist.","en":"I'm convinced that sport is healthy.","ru":"Я убеждён, что спорт полезен для здоровья.","vi":"Tôi tin rằng thể thao là lành mạnh.","fa":"من متقاعد شده ام که ورزش سالم است."}]},{"word":"Ich bin der Meinung, dass …","en":"I am of the opinion that … (formal opinion)","ru":"Я придерживаюсь мнения, что … (формально)","vi":"Tôi có quan điểm rằng…","fa":"من بر این عقیده هستم که…","examples":[{"de":"Ich bin der Meinung, dass Bildung kostenlos sein sollte.","en":"I am of the opinion that education should be free.","ru":"Я придерживаюсь мнения, что образование должно быть бесплатным.","vi":"Tôi tin rằng giáo dục nên được miễn phí.","fa":"من معتقدم که آموزش باید رایگان باشد."}]},{"word":"Ich bin ganz deiner Meinung","en":"I completely agree with you (agreement)","ru":"Я полностью с тобой согласен (согласие)","vi":"Tôi hoàn toàn đồng ý với bạn","fa":"من کاملا با شما موافقم","examples":[{"de":"Ich bin ganz deiner Meinung, wir sollten warten.","en":"I completely agree with you, we should wait.","ru":"Я полностью с тобой согласен, нам стоит подождать.","vi":"Tôi đồng ý với bạn, chúng ta nên chờ đợi.","fa":"باهات موافقم باید صبر کنیم"}]},{"word":"Ich bin mir nicht sicher, ob das stimmt","en":"I'm not sure if that's right (doubt)","ru":"Я не уверен, что это так (сомнение)","vi":"Tôi không chắc điều đó có đúng không","fa":"من مطمئن نیستم که آیا این درست است","examples":[{"de":"Ich bin mir nicht sicher, ob das stimmt.","en":"I'm not sure if that's right.","ru":"Я не уверен, что это так.","vi":"Tôi không chắc điều đó có đúng không.","fa":"من مطمئن نیستم که آیا این درست است."}]},{"word":"Ich bin mir (noch) nicht sicher","en":"I'm not sure (yet) (uncertainty)","ru":"Я (пока) не уверен (неуверенность)","vi":"tôi không chắc","fa":"من مطمئن نیستم","examples":[{"de":"Ich bin mir noch nicht sicher, ob ich komme.","en":"I'm not sure yet whether I'll come.","ru":"Я пока не уверен, приду ли я.","vi":"Tôi không chắc liệu tôi có đến được hay không.","fa":"هنوز مطمئن نیستم که بیایم یا نه."}]},{"word":"Ich denke, dass …","en":"I think that … (giving your view)","ru":"Я думаю, что … (выражение мнения)","vi":"Tôi nghĩ rằng…","fa":"فکر می کنم که…","examples":[{"de":"Ich denke, dass wir uns früh treffen sollten.","en":"I think that we should meet early.","ru":"Я думаю, что нам стоит встретиться пораньше.","vi":"Tôi nghĩ chúng ta nên gặp nhau sớm.","fa":"فکر می کنم باید زودتر همدیگر را ببینیم."}]},{"word":"Ich erinnere mich (daran), dass …","en":"I remember that … (recollection)","ru":"Я помню, что … (воспоминание)","vi":"Tôi nhớ điều đó…","fa":"یادم هست که…","examples":[{"de":"Ich erinnere mich daran, dass es damals viel geschneit hat.","en":"I remember that it snowed a lot back then.","ru":"Я помню, что тогда шло много снега.","vi":"Tôi nhớ hồi đó tuyết rơi rất nhiều.","fa":"یادم می آید آن زمان برف زیادی بارید."}]},{"word":"Ich finde, dass …","en":"I find/think that … (personal opinion)","ru":"Мне кажется, что … (личное мнение)","vi":"Tôi thấy/nghĩ rằng…","fa":"می یابم/فکر می کنم که…","examples":[{"de":"Ich finde, dass der Film sehr spannend war.","en":"I think that the film was very exciting.","ru":"Мне кажется, что фильм был очень захватывающим.","vi":"Tôi nghĩ bộ phim rất thú vị.","fa":"به نظرم فیلم خیلی هیجان انگیز بود."}]},{"word":"Ich glaube, dass …","en":"I believe that … (giving your view)","ru":"Я считаю, что … (выражение мнения)","vi":"Tôi tin rằng…","fa":"من معتقدم که…","examples":[{"de":"Ich glaube, dass das eine gute Lösung ist.","en":"I believe that this is a good solution.","ru":"Я считаю, что это хорошее решение.","vi":"Tôi tin rằng đây là một giải pháp tốt.","fa":"من معتقدم که این راه حل خوبی است."}]},{"word":"Ich habe den Eindruck, dass …","en":"I have the impression that … (impression)","ru":"У меня складывается впечатление, что … (впечатление)","vi":"Tôi có ấn tượng rằng…","fa":"من این تصور را دارم که…","examples":[{"de":"Ich habe den Eindruck, dass er müde ist.","en":"I have the impression that he is tired.","ru":"У меня складывается впечатление, что он устал.","vi":"Tôi có ấn tượng là anh ấy đang mệt mỏi.","fa":"من این تصور را دارم که او خسته است."}]},{"word":"Ich habe die Erfahrung gemacht, dass …","en":"I've found from experience that … (personal experience)","ru":"По своему опыту я знаю, что … (личный опыт)","vi":"Tôi đã nhận thấy từ kinh nghiệm rằng…","fa":"من به تجربه دریافتم که…","examples":[{"de":"Ich habe die Erfahrung gemacht, dass Übung wirklich hilft.","en":"I've found from experience that practice really helps.","ru":"По своему опыту я знаю, что практика действительно помогает.","vi":"Tôi nhận thấy rằng thực hành thực sự có ích.","fa":"من متوجه شده ام که تمرین واقعا کمک می کند."}]},{"word":"Ich hätte da einen Vorschlag","en":"I have a suggestion (introducing a suggestion)","ru":"У меня есть предложение (введение предложения)","vi":"Tôi có một gợi ý","fa":"من یک پیشنهاد دارم","examples":[{"de":"Ich hätte da einen Vorschlag: Wir teilen die Arbeit.","en":"I have a suggestion: let's split the work.","ru":"У меня есть предложение: давай разделим работу.","vi":"Tôi có một đề nghị: chúng ta hãy chia sẻ công việc.","fa":"من یک پیشنهاد دارم: ما کار را به اشتراک می گذاریم."}]},{"word":"Ich hätte gern …","en":"I would like … (polite request)","ru":"Я бы хотел … (вежливая просьба)","vi":"Tôi muốn…","fa":"من دوست دارم…","examples":[{"de":"Ich hätte gern einen Kaffee, bitte.","en":"I would like a coffee, please.","ru":"Я бы хотел кофе, пожалуйста.","vi":"Làm ơn cho tôi một ít cà phê.","fa":"من یک قهوه می خواهم، لطفا."}]},{"word":"Ich interessiere mich (sehr) für …","en":"I'm (very) interested in … (interest)","ru":"Я (очень) интересуюсь … (интерес)","vi":"Tôi quan tâm đến…","fa":"من علاقه مند به…","examples":[{"de":"Ich interessiere mich sehr für Geschichte.","en":"I'm very interested in history.","ru":"Я очень интересуюсь историей.","vi":"Tôi rất quan tâm đến lịch sử.","fa":"من به تاریخ علاقه زیادی دارم."}]},{"word":"Ich komme jetzt zum nächsten Punkt","en":"I'll now move on to the next point (structuring)","ru":"Теперь перехожу к следующему пункту (структура)","vi":"Bây giờ tôi sẽ chuyển sang điểm tiếp theo","fa":"اکنون به نکته بعدی می پردازم","examples":[{"de":"Ich komme jetzt zum nächsten Punkt, den Kosten.","en":"I'll now move on to the next point, the costs.","ru":"Теперь перехожу к следующему пункту — расходам.","vi":"Bây giờ tôi đến điểm tiếp theo, chi phí.","fa":"اکنون به نکته بعدی یعنی هزینه ها می رسم."}]},{"word":"Ich möchte euch heute … vorstellen","en":"Today I'd like to present … to you (introducing a topic)","ru":"Сегодня я хотел бы представить вам … (введение темы)","vi":"Hôm nay tôi muốn giới thiệu… với các bạn","fa":"امروز می خواهم … را به شما تقدیم کنم","examples":[{"de":"Ich möchte euch heute mein Lieblingshobby vorstellen.","en":"Today I'd like to present my favourite hobby to you.","ru":"Сегодня я хотел бы представить вам своё любимое хобби.","vi":"Hôm nay tôi muốn giới thiệu với các bạn sở thích yêu thích của tôi.","fa":"امروز می خواهم شما را با سرگرمی مورد علاقه ام آشنا کنم."}]},{"word":"Ich schlage vor, dass …","en":"I suggest that … (making a suggestion)","ru":"Я предлагаю, чтобы … (предложение)","vi":"Tôi đề nghị rằng…","fa":"پیشنهاد می کنم که…","examples":[{"de":"Ich schlage vor, dass wir zuerst essen.","en":"I suggest that we eat first.","ru":"Я предлагаю сначала поесть.","vi":"Tôi đề nghị chúng ta ăn trước.","fa":"پیشنهاد میکنم اول بخوریم"}]},{"word":"Ich würde lieber …","en":"I would rather … (preference)","ru":"Я бы предпочёл … (предпочтение)","vi":"Tôi thà…","fa":"ترجیح می دهم…","examples":[{"de":"Ich würde lieber zu Hause bleiben.","en":"I would rather stay at home.","ru":"Я бы предпочёл остаться дома.","vi":"Tôi thà ở nhà còn hơn.","fa":"ترجیح می دهم در خانه بمانم."}]},{"word":"ideal","en":"ideal","ru":"идеальный","vi":"lý tưởng","fa":"ایده آل","examples":[{"de":"Dieser Ort ist ideal für einen Urlaub.","en":"This place is ideal for a vacation.","ru":"Это место идеально подходит для отпуска.","vi":"Nơi này là lý tưởng cho một kỳ nghỉ.","fa":"این مکان برای تعطیلات ایده آل است."},{"de":"Es gibt keine ideale Lösung für dieses Problem.","en":"There is no ideal solution to this problem.","ru":"Идеального решения этой проблемы не существует.","vi":"Không có giải pháp lý tưởng cho vấn đề này.","fa":"هیچ راه حل ایده آلی برای این مشکل وجود ندارد."}]},{"word":"die Idee","en":"idea","ru":"идея","vi":"ý tưởng","fa":"ایده","examples":[{"de":"Das ist eine sehr gute Idee!","en":"That's a very good idea!","ru":"Это очень хорошая идея!","vi":"Đó là một ý tưởng rất tốt!","fa":"این ایده بسیار خوبی است!"},{"de":"Ich habe keine Idee, wie wir das Problem lösen sollen.","en":"I have no idea how we should solve this problem.","ru":"Я понятия не имею, как нам решить эту проблему.","vi":"Tôi không biết chúng ta nên giải quyết vấn đề như thế nào.","fa":"من نمی دانم چگونه باید مشکل را حل کنیم."}]},{"word":"illegal","en":"illegal","ru":"нелегальный, незаконный","vi":"bất hợp pháp","fa":"غیر قانونی","examples":[{"de":"Es ist illegal, ohne Ticket mit dem Zug zu fahren.","en":"It is illegal to travel by train without a ticket.","ru":"Ехать в поезде без билета незаконно.","vi":"Việc đi tàu mà không có vé là bất hợp pháp.","fa":"سوار شدن به قطار بدون بلیط غیرقانونی است."},{"de":"Der Verkäufer wurde wegen illegaler Geschäfte verhaftet.","en":"The seller was arrested for illegal business dealings.","ru":"Продавца арестовали за незаконные сделки.","vi":"Người bán đã bị bắt vì kinh doanh trái phép.","fa":"فروشنده به دلیل تجارت غیرقانونی دستگیر شد."}]},{"word":"im","en":"in the (in + dem)","ru":"в (in + dem)","vi":"trong","fa":"در","examples":[{"de":"Im Sommer fahren wir oft ans Meer.","en":"In summer we often go to the seaside.","ru":"Летом мы часто ездим на море.","vi":"Vào mùa hè chúng tôi thường đi biển.","fa":"در تابستان اغلب به دریا می رویم."},{"de":"Die Kinder spielen im Garten.","en":"The children are playing in the garden.","ru":"Дети играют в саду.","vi":"Bọn trẻ đang chơi trong vườn.","fa":"بچه ها در باغ بازی می کنند."},{"de":"Im Jahr 2020 hat sich vieles verändert.","en":"In 2020 a lot changed.","ru":"В 2020 году многое изменилось.","vi":"Rất nhiều thứ đã thay đổi vào năm 2020.","fa":"در سال 2020 خیلی چیزها تغییر کرده است."}]},{"word":"der Imbiss","en":"snack bar","ru":"закусочная","vi":"bữa ăn nhẹ","fa":"میان وعده","examples":[{"de":"An der Ecke gibt es einen Imbiss mit leckeren Currywürsten.","en":"There's a snack bar on the corner with delicious currywurst.","ru":"На углу есть закусочная с вкусными карривурстами.","vi":"Có một quán ăn nhanh ở góc phố với món xúc xích cà ri thơm ngon.","fa":"یک اسنک بار در گوشه ای با سوسیس های کاری خوشمزه وجود دارد."},{"de":"Wir haben schnell etwas am Imbiss gegessen.","en":"We quickly ate something at the snack bar.","ru":"Мы быстро перекусили в закусочной.","vi":"Chúng tôi nhanh chóng ăn thứ gì đó ở quầy bán đồ ăn nhanh.","fa":"ما سریع چیزی در اسنک بار خوردیم."}]},{"word":"immer","en":"always","ru":"всегда","vi":"luôn luôn","fa":"همیشه","examples":[{"de":"Er kommt immer pünktlich zur Arbeit.","en":"He always comes to work on time.","ru":"Он всегда приходит на работу вовремя.","vi":"Anh ấy luôn đi làm đúng giờ.","fa":"او همیشه سر وقت سر کار می آید."},{"de":"Ich werde dich immer unterstützen.","en":"I will always support you.","ru":"Я всегда буду тебя поддерживать.","vi":"Tôi sẽ luôn ủng hộ bạn.","fa":"من همیشه از شما حمایت خواهم کرد."}]},{"word":"die Impfung","en":"vaccination","ru":"прививка; вакцинация","vi":"tiêm chủng","fa":"واکسیناسیون","examples":[{"de":"Die Impfung schützt vor einer schweren Erkrankung.","en":"The vaccination protects against a serious illness.","ru":"Прививка защищает от тяжёлого заболевания.","vi":"Việc chủng ngừa bảo vệ chống lại bệnh tật nghiêm trọng.","fa":"واکسیناسیون در برابر بیماری های جدی محافظت می کند."},{"de":"Für die Reise brauchst du eine bestimmte Impfung.","en":"For the trip you need a certain vaccination.","ru":"Для поездки тебе нужна определённая прививка.","vi":"Bạn cần tiêm phòng cụ thể cho chuyến đi.","fa":"برای سفر به واکسیناسیون خاصی نیاز دارید."}]},{"word":"der Import","en":"import","ru":"импорт","vi":"việc nhập khẩu","fa":"واردات","examples":[{"de":"Der Import von Obst aus Südamerika hat zugenommen.","en":"The import of fruit from South America has increased.","ru":"Импорт фруктов из Южной Америки увеличился.","vi":"Việc nhập khẩu trái cây từ Nam Mỹ đã tăng lên.","fa":"واردات میوه از آمریکای جنوبی افزایش یافته است."},{"de":"Diese Firma lebt hauptsächlich vom Import und Export von Waren.","en":"This company mainly lives from the import and export of goods.","ru":"Эта фирма живёт в основном за счёт импорта и экспорта товаров.","vi":"Công ty này chủ yếu sống nhờ xuất nhập khẩu hàng hóa.","fa":"این شرکت عمدتاً از واردات و صادرات کالا زندگی می کند."}]},{"word":"der Impuls","en":"momentum","ru":"импульс (в физике)","vi":"sự thúc đẩy","fa":"انگیزه","examples":[{"de":"Der Impuls eines Körpers ist Masse mal Geschwindigkeit.","en":"The momentum of a body is mass times velocity.","ru":"Импульс тела — это масса, умноженная на скорость.","vi":"Động lượng của một vật bằng khối lượng nhân với tốc độ.","fa":"تکانه یک جسم برابر است با جرم ضربدر سرعت."},{"de":"Beim Stoß wird der Impuls von der einen Kugel auf die andere übertragen.","en":"In a collision the momentum is transferred from one ball to the other.","ru":"При столкновении импульс передаётся от одного шара к другому.","vi":"Khi va chạm, động lượng được truyền từ quả bóng này sang quả bóng kia.","fa":"در هنگام برخورد، تکانه از یک توپ به توپ دیگر منتقل می شود."},{"de":"Ein schwerer Lkw hat bei gleicher Geschwindigkeit einen größeren Impuls.","en":"A heavy lorry has greater momentum at the same speed.","ru":"У тяжёлого грузовика при той же скорости больший импульс.","vi":"Một chiếc xe tải hạng nặng có động lượng lớn hơn ở cùng tốc độ.","fa":"یک کامیون سنگین در همان سرعت حرکت بیشتری دارد."}]},{"word":"in","en":"in","ru":"в","vi":"trong","fa":"در","examples":[{"de":"Die Schlüssel liegen in der Tasche.","en":"The keys are in the bag.","ru":"Ключи лежат в сумке.","vi":"Chìa khóa ở trong túi.","fa":"کلیدها داخل کیف هستند."},{"de":"Wir treffen uns in einer Stunde.","en":"We'll meet in an hour.","ru":"Мы встретимся через час.","vi":"Chúng ta sẽ gặp nhau trong một giờ nữa.","fa":"یه ساعت دیگه همدیگه رو میبینیم"}]},{"word":"In meinem Heimatland ist das so: …","en":"In my home country it's like this: … (talking about your country)","ru":"В моей стране это так: … (о своей стране)","vi":"Ở quê hương tôi nó như thế này:…","fa":"در کشور من اینگونه است: …","examples":[{"de":"In meinem Heimatland ist das so: Man isst spät zu Abend.","en":"In my home country it's like this: people eat dinner late.","ru":"В моей стране это так: ужинают поздно.","vi":"Ở quê hương tôi nó như thế này: bạn ăn tối muộn.","fa":"در کشور من اینگونه است: شام را دیر می خوری."}]},{"word":"In meiner Präsentation geht es um …","en":"My presentation is about … (opening a presentation)","ru":"Моя презентация посвящена … (начало презентации)","vi":"Bài thuyết trình của tôi là về…","fa":"ارائه من در مورد…","examples":[{"de":"In meiner Präsentation geht es um das Thema Umwelt.","en":"My presentation is about the topic of the environment.","ru":"Моя презентация посвящена теме окружающей среды.","vi":"Bài thuyết trình của tôi là về chủ đề môi trường.","fa":"ارائه من در مورد موضوع محیط زیست است."}]},{"word":"in Pension/Rente gehen (pensioniert werden)","en":"to retire","ru":"выходить на пенсию","vi":"nghỉ hưu/nghỉ hưu (được nghỉ hưu)","fa":"بازنشسته/بازنشسته (بازنشسته)","examples":[{"de":"Mein Vater geht nächstes Jahr in Pension.","en":"My father is retiring next year.","ru":"Мой отец выходит на пенсию в следующем году.","vi":"Bố tôi sẽ nghỉ hưu vào năm tới.","fa":"پدرم سال آینده بازنشسته می شود."},{"de":"Sie freut sich schon darauf, in Rente zu gehen.","en":"She is already looking forward to retiring.","ru":"Она уже радуется выходу на пенсию.","vi":"Cô ấy đang mong chờ được nghỉ hưu.","fa":"او مشتاقانه منتظر بازنشستگی است."}]},{"word":"indem","en":"by (doing something)","ru":"тем, что; посредством того, что","vi":"bởi","fa":"توسط","examples":[{"de":"Du kannst Geld sparen, indem du weniger einkaufst.","en":"You can save money by shopping less.","ru":"Ты можешь экономить деньги, покупая меньше.","vi":"Bạn có thể tiết kiệm tiền bằng cách mua sắm ít hơn.","fa":"با خرید کمتر می توانید در پول خود صرفه جویی کنید."},{"de":"Er verbesserte sein Deutsch, indem er jeden Tag las.","en":"He improved his German by reading every day.","ru":"Он улучшил свой немецкий, читая каждый день.","vi":"Anh ấy đã cải thiện tiếng Đức của mình bằng cách đọc sách mỗi ngày.","fa":"او با خواندن هر روز آلمانی خود را بهبود بخشید."}]},{"word":"individuell","en":"individual","ru":"индивидуальный","vi":"cá nhân","fa":"به صورت جداگانه","examples":[{"de":"Jeder Kunde bekommt eine individuelle Beratung.","en":"Every customer gets individual advice.","ru":"Каждый клиент получает индивидуальную консультацию.","vi":"Mỗi khách hàng đều nhận được lời khuyên riêng.","fa":"هر مشتری مشاوره فردی دریافت می کند."},{"de":"Das Hotelzimmer wurde individuell eingerichtet.","en":"The hotel room was individually furnished.","ru":"Гостиничный номер был обставлен индивидуально.","vi":"Phòng khách sạn được trang bị nội thất riêng.","fa":"اتاق هتل به صورت مجزا مبله شده بود."}]},{"word":"die Industrie","en":"industry","ru":"промышленность","vi":"ngành công nghiệp","fa":"صنعت","examples":[{"de":"Die Industrie in dieser Region wächst schnell.","en":"Industry in this region is growing fast.","ru":"Промышленность в этом регионе быстро растёт.","vi":"Ngành công nghiệp ở khu vực này đang phát triển nhanh chóng.","fa":"صنعت در این منطقه به سرعت در حال رشد است."},{"de":"Viele Menschen arbeiten in der Autoindustrie.","en":"Many people work in the automotive industry.","ru":"Многие люди работают в автомобильной промышленности.","vi":"Nhiều người làm việc trong ngành công nghiệp ô tô.","fa":"افراد زیادی در صنعت خودرو کار می کنند."}]},{"word":"die Infektion","en":"infection","ru":"инфекция","vi":"nhiễm trùng","fa":"عفونت","examples":[{"de":"Der Arzt hat eine Infektion in der Wunde festgestellt.","en":"The doctor found an infection in the wound.","ru":"Врач обнаружил инфекцию в ране.","vi":"Bác sĩ phát hiện vết thương bị nhiễm trùng.","fa":"دکتر متوجه عفونت در زخم شد."},{"de":"Ohne Behandlung kann sich die Infektion ausbreiten.","en":"Without treatment, the infection can spread.","ru":"Без лечения инфекция может распространиться.","vi":"Nếu không điều trị, nhiễm trùng có thể lây lan.","fa":"بدون درمان، عفونت می تواند گسترش یابد."}]},{"word":"informieren","en":"to inform","ru":"информировать","vi":"thông báo","fa":"اطلاع رسانی کند","examples":[{"de":"Bitte informieren Sie mich, sobald Sie Neuigkeiten haben.","en":"Please inform me as soon as you have news.","ru":"Пожалуйста, проинформируйте меня, как только у вас будут новости.","vi":"Xin vui lòng cho tôi biết ngay khi bạn có tin tức.","fa":"لطفا به محض اطلاع از این خبر به من اطلاع دهید."},{"de":"Wir haben uns vor der Reise gut über das Land informiert.","en":"We informed ourselves well about the country before the trip.","ru":"Перед поездкой мы хорошо изучили информацию о стране.","vi":"Chúng tôi đã thông báo rõ về đất nước này trước chuyến đi.","fa":"قبل از سفر به خوبی از کشور مطلع شدیم."}]},{"word":"der Ingenieur","en":"engineer","ru":"инженер","vi":"kỹ sư","fa":"مهندس","examples":[{"de":"Mein Bruder arbeitet als Ingenieur bei einer Autofirma.","en":"My brother works as an engineer at a car company.","ru":"Мой брат работает инженером в автомобильной компании.","vi":"Anh trai tôi làm kỹ sư ở một công ty ô tô.","fa":"برادرم در یک شرکت خودروسازی به عنوان مهندس کار می کند."},{"de":"Sie hat Maschinenbau studiert und ist jetzt Ingenieurin.","en":"She studied mechanical engineering and is now an engineer.","ru":"Она изучала машиностроение и теперь работает инженером.","vi":"Cô học ngành cơ khí và hiện là kỹ sư.","fa":"او مهندسی مکانیک خوانده و اکنون مهندس است."}]},{"word":"der Inhalt","en":"content","ru":"содержание","vi":"nội dung","fa":"محتوا","examples":[{"de":"Der Inhalt des Buches hat mich sehr überrascht.","en":"The content of the book surprised me a lot.","ru":"Содержание книги меня очень удивило.","vi":"Nội dung của cuốn sách thực sự làm tôi ngạc nhiên.","fa":"محتوای کتاب واقعاً مرا شگفت زده کرد."},{"de":"Bitte überprüfen Sie den Inhalt der Verpackung.","en":"Please check the contents of the package.","ru":"Пожалуйста, проверьте содержимое упаковки.","vi":"Vui lòng kiểm tra nội dung của bao bì.","fa":"لطفا محتویات بسته بندی را بررسی کنید."}]},{"word":"inklusive","en":"including","ru":"включая, включительно","vi":"bao gồm","fa":"فراگیر","examples":[{"de":"Der Preis ist inklusive Frühstück.","en":"The price includes breakfast.","ru":"Цена включает завтрак.","vi":"Giá bao gồm bữa sáng.","fa":"قیمت شامل صبحانه می باشد."},{"de":"Die Miete beträgt 600 Euro inklusive Nebenkosten.","en":"The rent is 600 euros including utilities.","ru":"Аренда составляет 600 евро, включая коммунальные услуги.","vi":"Giá thuê là 600 euro bao gồm cả chi phí bổ sung.","fa":"اجاره با احتساب هزینه اضافی 600 یورو می باشد."}]},{"word":"innen","en":"inside","ru":"внутри","vi":"bên trong","fa":"داخل","examples":[{"de":"Das Haus sieht von außen alt aus, aber innen ist es modern.","en":"The house looks old from outside, but inside it is modern.","ru":"Дом снаружи выглядит старым, но внутри он современный.","vi":"Ngôi nhà nhìn bên ngoài có vẻ cũ kỹ nhưng bên trong lại hiện đại.","fa":"خانه از بیرون قدیمی به نظر می رسد، اما درون آن مدرن است."},{"de":"Die Tür lässt sich nur von innen öffnen.","en":"The door can only be opened from the inside.","ru":"Дверь можно открыть только изнутри.","vi":"Cánh cửa chỉ có thể được mở từ bên trong.","fa":"درب فقط از داخل باز می شود."}]},{"word":"inner","en":"inner, internal","ru":"внутренний","vi":"nội bộ","fa":"داخلی","examples":[{"de":"Sie fand innere Ruhe durch Meditation.","en":"She found inner peace through meditation.","ru":"Через медитацию она обрела внутренний покой.","vi":"Cô tìm thấy sự bình yên nội tâm nhờ thiền định.","fa":"او از طریق مدیتیشن به آرامش درونی دست یافت."},{"de":"Die inneren Organe müssen gut geschützt werden.","en":"The internal organs need to be well protected.","ru":"Внутренние органы нужно хорошо защищать.","vi":"Các cơ quan nội tạng phải được bảo vệ tốt.","fa":"اندام های داخلی باید به خوبی محافظت شوند."},{"de":"Er hatte starke innere Zweifel an dem Plan.","en":"He had strong inner doubts about the plan.","ru":"У него были сильные внутренние сомнения по поводу плана.","vi":"Trong thâm tâm anh có những nghi ngờ mạnh mẽ về kế hoạch này.","fa":"او تردیدهای درونی شدیدی در مورد این طرح داشت."}]},{"word":"innerhalb","en":"within, inside (of)","ru":"в пределах, внутри (чего-либо)","vi":"bên trong","fa":"در داخل","examples":[{"de":"Bitte antworten Sie innerhalb von drei Tagen.","en":"Please reply within three days.","ru":"Ответьте, пожалуйста, в течение трёх дней.","vi":"Vui lòng trả lời trong vòng ba ngày.","fa":"لطفا ظرف سه روز پاسخ دهید."},{"de":"Innerhalb der Stadt gibt es viele Parks.","en":"Within the city there are many parks.","ru":"В пределах города много парков.","vi":"Có rất nhiều công viên trong thành phố.","fa":"پارک های زیادی در داخل شهر وجود دارد."},{"de":"Die Aufgabe muss innerhalb einer Stunde fertig sein.","en":"The task must be finished within an hour.","ru":"Задачу нужно закончить в течение часа.","vi":"Nhiệm vụ phải được hoàn thành trong vòng một giờ.","fa":"کار باید در عرض یک ساعت انجام شود."}]},{"word":"ins Fettnäpfchen treten","en":"to put one's foot in it (say something awkward)","ru":"сесть в лужу, сказать бестактность","vi":"đặt chân vào đó","fa":"پا گذاشتن در آن","examples":[{"de":"Mit der Frage nach dem Alter bin ich ins Fettnäpfchen getreten.","en":"With the question about her age I really put my foot in it.","ru":"Вопросом о возрасте я сел в лужу.","vi":"Tôi đã mắc sai lầm lớn khi hỏi về tuổi tác.","fa":"وقتی از سن پرسیدم اشتباه بزرگی کردم."}]},{"word":"ins kalte Wasser springen","en":"to jump in at the deep end","ru":"броситься в омут с головой, начать без подготовки","vi":"nhảy vào nơi tận cùng sâu thẳm","fa":"برای پریدن در انتهای عمیق","examples":[{"de":"Beim neuen Job musste ich gleich ins kalte Wasser springen.","en":"At the new job I had to jump in at the deep end straight away.","ru":"На новой работе мне сразу пришлось прыгнуть в омут с головой.","vi":"Với công việc mới, tôi phải lao thẳng vào vực sâu.","fa":"با کار جدید، مجبور شدم مستقیماً به عمق کار بپرم."}]},{"word":"die Insel","en":"island","ru":"остров","vi":"hòn đảo","fa":"جزیره","examples":[{"de":"Wir haben unseren Urlaub auf einer kleinen Insel verbracht.","en":"We spent our vacation on a small island.","ru":"Мы провели отпуск на маленьком острове.","vi":"Chúng tôi dành kỳ nghỉ của mình trên một hòn đảo nhỏ.","fa":"تعطیلاتمان را در یک جزیره کوچک گذراندیم."},{"de":"Die Insel ist nur mit dem Boot erreichbar.","en":"The island can only be reached by boat.","ru":"На остров можно добраться только на лодке.","vi":"Đảo chỉ có thể đến được bằng thuyền.","fa":"دسترسی به جزیره فقط با قایق امکان پذیر است."}]},{"word":"das Inserat","en":"advertisement, classified ad","ru":"объявление","vi":"quảng cáo","fa":"تبلیغ","examples":[{"de":"Ich habe ein Inserat für die Wohnung in der Zeitung aufgegeben.","en":"I placed an ad for the apartment in the newspaper.","ru":"Я разместил объявление о квартире в газете.","vi":"Tôi đã đăng một quảng cáo về căn hộ trên báo.","fa":"آگهی آپارتمان را در روزنامه گذاشتم."},{"de":"In dem Inserat stand, dass das Auto sehr günstig ist.","en":"The ad said that the car is very cheap.","ru":"В объявлении говорилось, что машина очень дешёвая.","vi":"Quảng cáo cho biết chiếc xe này rất rẻ.","fa":"در آگهی آمده بود که ماشین بسیار ارزان است."}]},{"word":"insgesamt","en":"in total","ru":"в общей сложности, всего","vi":"tổng thể","fa":"به طور کلی","examples":[{"de":"Wir waren insgesamt zehn Personen auf der Party.","en":"We were ten people in total at the party.","ru":"На вечеринке было в общей сложности десять человек.","vi":"Tổng cộng có mười người chúng tôi ở bữa tiệc.","fa":"در مجموع ده نفر در مهمانی بودیم."},{"de":"Die Reise hat insgesamt zwei Wochen gedauert.","en":"The trip lasted two weeks in total.","ru":"Поездка длилась в общей сложности две недели.","vi":"Chuyến đi kéo dài tổng cộng hai tuần.","fa":"این سفر در مجموع دو هفته طول کشید."}]},{"word":"die Installation","en":"installation","ru":"установка (программы)","vi":"việc cài đặt","fa":"نصب","examples":[{"de":"Die Installation des Programms dauert nur wenige Minuten.","en":"The installation of the program takes only a few minutes.","ru":"Установка программы занимает всего несколько минут.","vi":"Việc cài đặt chương trình chỉ mất vài phút.","fa":"نصب برنامه فقط چند دقیقه طول می کشد."},{"de":"Während der Installation darfst du den Computer nicht ausschalten.","en":"During the installation you mustn't turn off the computer.","ru":"Во время установки нельзя выключать компьютер.","vi":"Bạn không được tắt máy tính trong khi cài đặt.","fa":"هنگام نصب نباید کامپیوتر را خاموش کنید."},{"de":"Nach der Installation musst du das Gerät neu starten.","en":"After the installation you have to restart the device.","ru":"После установки нужно перезапустить устройство.","vi":"Sau khi cài đặt bạn cần khởi động lại thiết bị.","fa":"پس از نصب باید دستگاه را ریستارت کنید."}]},{"word":"installieren","en":"to install","ru":"устанавливать","vi":"cài đặt","fa":"نصب کنید","examples":[{"de":"Kannst du mir helfen, das neue Programm zu installieren?","en":"Can you help me install the new program?","ru":"Можешь помочь мне установить новую программу?","vi":"Bạn có thể giúp tôi cài đặt chương trình mới được không?","fa":"میشه کمکم کنید برنامه جدید رو نصب کنم؟"},{"de":"Der Techniker hat die neue Software auf allen Computern installiert.","en":"The technician installed the new software on all computers.","ru":"Техник установил новое программное обеспечение на все компьютеры.","vi":"Kỹ thuật viên đã cài đặt phần mềm mới trên tất cả các máy tính.","fa":"تکنسین نرم افزار جدید را روی همه رایانه ها نصب کرد."}]},{"word":"das Institut","en":"institute","ru":"институт","vi":"viện","fa":"موسسه","examples":[{"de":"Sie arbeitet an einem Institut für Sprachforschung.","en":"She works at an institute for language research.","ru":"Она работает в институте языковых исследований.","vi":"Cô làm việc tại một viện nghiên cứu ngôn ngữ.","fa":"او در یک موسسه تحقیقات زبان کار می کند."},{"de":"Das Institut bietet auch Deutschkurse für Ausländer an.","en":"The institute also offers German courses for foreigners.","ru":"Институт также предлагает курсы немецкого языка для иностранцев.","vi":"Viện cũng cung cấp các khóa học tiếng Đức cho người nước ngoài.","fa":"این موسسه همچنین دوره های زبان آلمانی را برای خارجی ها ارائه می دهد."}]},{"word":"das Instrument","en":"instrument","ru":"инструмент","vi":"nhạc cụ","fa":"ساز","examples":[{"de":"Spielst du ein musikalisches Instrument?","en":"Do you play a musical instrument?","ru":"Ты играешь на каком-нибудь музыкальном инструменте?","vi":"Bạn có chơi một nhạc cụ không?","fa":"آیا ساز موسیقی می نوازی؟"},{"de":"Die Gitarre ist mein Lieblingsinstrument.","en":"The guitar is my favorite instrument.","ru":"Гитара — мой любимый инструмент.","vi":"Guitar là nhạc cụ yêu thích của tôi.","fa":"گیتار ساز مورد علاقه من است."}]},{"word":"integrieren","en":"to integrate","ru":"интегрировать","vi":"tích hợp","fa":"ادغام کردن","examples":[{"de":"Es dauert Zeit, sich in ein neues Land zu integrieren.","en":"It takes time to integrate into a new country.","ru":"Нужно время, чтобы интегрироваться в новую страну.","vi":"Cần có thời gian để hòa nhập vào một đất nước mới.","fa":"ادغام در یک کشور جدید به زمان نیاز دارد."},{"de":"Die Schule versucht, alle Kinder gut zu integrieren.","en":"The school tries to integrate all children well.","ru":"Школа старается хорошо интегрировать всех детей.","vi":"Nhà trường cố gắng hòa nhập tốt với tất cả trẻ em.","fa":"مدرسه سعی می کند همه بچه ها را به خوبی ادغام کند."}]},{"word":"intelligent","en":"intelligent","ru":"умный","vi":"thông minh","fa":"باهوش","examples":[{"de":"Meine Kollegin ist sehr intelligent und löst Probleme schnell.","en":"My colleague is very intelligent and solves problems quickly.","ru":"Моя коллега очень умная и быстро решает проблемы.","vi":"Đồng nghiệp của tôi rất thông minh và giải quyết vấn đề nhanh chóng.","fa":"همکار من بسیار باهوش است و مشکلات را به سرعت حل می کند."},{"de":"Hunde gelten als intelligente Tiere.","en":"Dogs are considered intelligent animals.","ru":"Собаки считаются умными животными.","vi":"Chó được coi là loài động vật thông minh.","fa":"سگ ها حیوانات باهوشی محسوب می شوند."}]},{"word":"die Intelligenz","en":"intelligence","ru":"интеллект, ум","vi":"trí thông minh","fa":"هوش","examples":[{"de":"Künstliche Intelligenz verändert unsere Arbeitswelt.","en":"Artificial intelligence is changing our working world.","ru":"Искусственный интеллект меняет наш мир труда.","vi":"Trí tuệ nhân tạo đang thay đổi thế giới làm việc của chúng ta.","fa":"هوش مصنوعی دنیای کار ما را تغییر می دهد."},{"de":"Seine Intelligenz zeigte sich schon in der Schule.","en":"His intelligence was already evident at school.","ru":"Его ум проявился уже в школе.","vi":"Trí thông minh của anh ấy được thể hiện rõ ràng ngay cả ở trường.","fa":"هوش او حتی در مدرسه مشهود بود."},{"de":"Man kann Intelligenz nicht nur an Noten messen.","en":"You cannot measure intelligence by grades alone.","ru":"Интеллект нельзя измерить одними оценками.","vi":"Bạn không thể đo lường trí thông minh chỉ bằng điểm số.","fa":"شما نمی توانید هوش را فقط با نمرات اندازه گیری کنید."}]},{"word":"intensiv","en":"intensive","ru":"интенсивный","vi":"mãnh liệt","fa":"شدید","examples":[{"de":"Er hat sich intensiv auf die Prüfung vorbereitet.","en":"He prepared intensively for the exam.","ru":"Он интенсивно готовился к экзамену.","vi":"Anh ấy đã chuẩn bị kỹ lưỡng cho kỳ thi.","fa":"او به شدت برای امتحان آماده شد."},{"de":"Der Sprachkurs ist sehr intensiv, wir lernen jeden Tag.","en":"The language course is very intensive, we learn every day.","ru":"Языковой курс очень интенсивный, мы учимся каждый день.","vi":"Khóa học ngôn ngữ rất chuyên sâu, chúng tôi học hàng ngày.","fa":"دوره زبان بسیار فشرده است، ما هر روز یاد می گیریم."}]},{"word":"der Intensivkurs","en":"intensive course","ru":"интенсивный курс","vi":"khóa học chuyên sâu","fa":"دوره فشرده","examples":[{"de":"Im Sommer mache ich einen Intensivkurs in Spanisch.","en":"In summer I am taking an intensive course in Spanish.","ru":"Летом я прохожу интенсивный курс испанского.","vi":"Vào mùa hè, tôi đang tham gia một khóa học chuyên sâu về tiếng Tây Ban Nha.","fa":"در تابستان در حال گذراندن دوره فشرده زبان اسپانیایی هستم."},{"de":"Der Intensivkurs dauert vier Wochen mit täglichem Unterricht.","en":"The intensive course lasts four weeks with daily lessons.","ru":"Интенсивный курс длится четыре недели с ежедневными занятиями.","vi":"Khóa học chuyên sâu kéo dài bốn tuần với các bài học hàng ngày.","fa":"دوره فشرده چهار هفته با دروس روزانه است."},{"de":"Nach dem Intensivkurs konnte sie viel besser sprechen.","en":"After the intensive course she could speak much better.","ru":"После интенсивного курса она заговорила гораздо лучше.","vi":"Sau khóa học chuyên sâu, cô đã có thể nói tốt hơn nhiều.","fa":"بعد از دوره فشرده توانست خیلی بهتر صحبت کند."}]},{"word":"interessant","en":"interesting","ru":"интересный","vi":"thú vị","fa":"جالب","examples":[{"de":"Das ist ein sehr interessantes Buch über Geschichte.","en":"That is a very interesting book about history.","ru":"Это очень интересная книга по истории.","vi":"Đây là một cuốn sách rất thú vị về lịch sử.","fa":"این یک کتاب بسیار جالب در مورد تاریخ است."},{"de":"Sie hat einen interessanten Vortrag gehalten.","en":"She gave an interesting talk.","ru":"Она прочитала интересный доклад.","vi":"Cô đã có một bài giảng thú vị.","fa":"او سخنرانی جالبی کرد."},{"de":"Die Reise war interessant und lehrreich.","en":"The trip was interesting and instructive.","ru":"Поездка была интересной и познавательной.","vi":"Chuyến đi thật thú vị và mang tính giáo dục.","fa":"سفر جالب و آموزنده بود."}]},{"word":"interessieren","en":"to interest","ru":"интересовать","vi":"quan tâm","fa":"علاقه مند است","examples":[{"de":"Politik interessiert mich sehr.","en":"Politics interests me a lot.","ru":"Меня очень интересует политика.","vi":"Tôi rất quan tâm đến chính trị.","fa":"من به سیاست علاقه زیادی دارم."},{"de":"Interessierst du dich für klassische Musik?","en":"Are you interested in classical music?","ru":"Ты интересуешься классической музыкой?","vi":"Bạn có quan tâm đến âm nhạc cổ điển?","fa":"آیا به موسیقی کلاسیک علاقه دارید؟"}]},{"word":"interessiert","en":"interested","ru":"заинтересованный","vi":"quan tâm","fa":"علاقه مند است","examples":[{"de":"Ich bin sehr an diesem Job interessiert.","en":"I am very interested in this job.","ru":"Я очень заинтересован в этой работе.","vi":"Tôi rất hứng thú với công việc này.","fa":"من خیلی به این کار علاقه دارم."},{"de":"Sie ist an Kunst und Musik interessiert.","en":"She is interested in art and music.","ru":"Она интересуется искусством и музыкой.","vi":"Cô ấy quan tâm đến nghệ thuật và âm nhạc.","fa":"او به هنر و موسیقی علاقه دارد."},{"de":"Die Schüler hörten interessiert zu.","en":"The pupils listened with interest.","ru":"Ученики слушали с интересом.","vi":"Các học sinh lắng nghe với sự thích thú.","fa":"دانش آموزان با علاقه گوش دادند."}]},{"word":"interkulturell","en":"intercultural","ru":"межкультурный","vi":"liên văn hóa","fa":"بین فرهنگی","examples":[{"de":"Der interkulturelle Austausch hilft, andere Kulturen zu verstehen.","en":"Intercultural exchange helps to understand other cultures.","ru":"Межкультурный обмен помогает понять другие культуры.","vi":"Trao đổi liên văn hóa giúp hiểu biết các nền văn hóa khác.","fa":"تبادل بین فرهنگی به درک فرهنگ های دیگر کمک می کند."},{"de":"An der Universität gibt es ein Projekt zur interkulturellen Kommunikation.","en":"There is a project on intercultural communication at the university.","ru":"В университете есть проект по межкультурной коммуникации.","vi":"Có một dự án về giao tiếp liên văn hóa tại trường đại học.","fa":"پروژه ای در زمینه ارتباطات بین فرهنگی در دانشگاه وجود دارد."}]},{"word":"international","en":"international","ru":"международный","vi":"quốc tế","fa":"بین المللی","examples":[{"de":"Er arbeitet für ein internationales Unternehmen.","en":"He works for an international company.","ru":"Он работает в международной компании.","vi":"Anh ấy làm việc cho một công ty quốc tế.","fa":"او برای یک شرکت بین المللی کار می کند."},{"de":"Morgen findet ein internationales Fußballspiel statt.","en":"Tomorrow there is an international football match.","ru":"Завтра состоится международный футбольный матч.","vi":"Có một trận đấu bóng đá quốc tế vào ngày mai.","fa":"فردا یک مسابقه بین المللی فوتبال برگزار می شود."}]},{"word":"das Interview","en":"interview","ru":"интервью","vi":"cuộc phỏng vấn","fa":"مصاحبه","examples":[{"de":"Der Journalist führte ein Interview mit dem Bürgermeister.","en":"The journalist conducted an interview with the mayor.","ru":"Журналист взял интервью у мэра.","vi":"Nhà báo đã thực hiện cuộc phỏng vấn với thị trưởng.","fa":"این روزنامه نگار با شهردار مصاحبه ای انجام داد."},{"de":"Ich habe morgen ein Interview für einen neuen Job.","en":"I have an interview for a new job tomorrow.","ru":"Завтра у меня собеседование на новую работу.","vi":"Tôi có một cuộc phỏng vấn cho công việc mới vào ngày mai.","fa":"فردا برای کار جدید مصاحبه دارم."}]},{"word":"inzwischen","en":"meanwhile","ru":"тем временем, между тем","vi":"trong khi đó","fa":"در همین حال","examples":[{"de":"Ich koche das Essen, du kannst inzwischen den Tisch decken.","en":"I'll cook the food, meanwhile you can set the table.","ru":"Я приготовлю еду, а ты пока можешь накрыть на стол.","vi":"Tôi sẽ nấu đồ ăn, trong lúc đó bạn có thể dọn bàn ăn.","fa":"من غذا را می پزم، شما می توانید در این فاصله سفره را بچینید."},{"de":"Er ist inzwischen erwachsen und wohnt allein.","en":"He is now grown up and lives alone.","ru":"Он тем временем вырос и живёт один.","vi":"Hiện anh đã trưởng thành và sống một mình.","fa":"او اکنون بالغ است و تنها زندگی می کند."}]},{"word":"irgend-","en":"some- (indefinite prefix)","ru":"какой-то, кое- (неопределённый префикс)","vi":"bằng cách nào đó-","fa":"به نحوی-","examples":[{"de":"Ich habe meinen Schlüssel irgendwo verloren.","en":"I lost my key somewhere.","ru":"Я где-то потерял свой ключ.","vi":"Tôi bị mất chìa khóa ở đâu đó.","fa":"کلیدم را جایی گم کردم."},{"de":"Frag doch irgendjemanden nach dem Weg.","en":"Just ask someone for directions.","ru":"Спроси кого-нибудь, как пройти.","vi":"Hãy hỏi bất cứ ai để được hướng dẫn.","fa":"از هر کسی راهنمایی بخواهید"}]},{"word":"irgendein","en":"some, any (one)","ru":"какой-нибудь, любой","vi":"bất kỳ","fa":"هر","examples":[{"de":"Hast du irgendein Buch über Italien?","en":"Do you have any book about Italy?","ru":"У тебя есть какая-нибудь книга об Италии?","vi":"Bạn có cuốn sách nào về Ý không?","fa":"آیا کتابی در مورد ایتالیا دارید؟"},{"de":"Irgendein Mann hat nach dir gefragt.","en":"Some man asked for you.","ru":"Тебя спрашивал какой-то мужчина.","vi":"Có người đàn ông nào đó hỏi về bạn.","fa":"مردی در مورد شما پرسید."},{"de":"Gib mir bitte irgendeinen Stift.","en":"Please give me any pen.","ru":"Дай мне, пожалуйста, любую ручку.","vi":"Làm ơn cho tôi một loại bút.","fa":"لطفاً یک قلم به من بدهید."}]},{"word":"irgendetwas","en":"something, anything","ru":"что-нибудь, что-то","vi":"bất cứ điều gì","fa":"هر چیزی","examples":[{"de":"Möchtest du irgendetwas trinken?","en":"Would you like anything to drink?","ru":"Хотите чего-нибудь выпить?","vi":"Bạn có muốn uống gì không?","fa":"آیا می خواهید چیزی بنوشید؟"},{"de":"Irgendetwas stimmt hier nicht.","en":"Something isn't right here.","ru":"Что-то тут не так.","vi":"Có gì đó không ổn ở đây.","fa":"اینجا یه چیزی اشتباهه"},{"de":"Hast du irgendetwas von ihm gehört?","en":"Have you heard anything from him?","ru":"Ты что-нибудь слышал о нём?","vi":"Bạn có nghe thấy gì từ anh ấy không?","fa":"آیا چیزی از او شنیده اید؟"}]},{"word":"irgendjemand","en":"someone, anyone","ru":"кто-нибудь, кто-то","vi":"bất cứ ai","fa":"هر کسی","examples":[{"de":"Hat irgendjemand meinen Schlüssel gesehen?","en":"Has anyone seen my key?","ru":"Кто-нибудь видел мой ключ?","vi":"Có ai nhìn thấy chìa khóa của tôi không?","fa":"کسی کلید من را دیده است؟"},{"de":"Irgendjemand muss die Tür offen gelassen haben.","en":"Someone must have left the door open.","ru":"Кто-то, наверное, оставил дверь открытой.","vi":"Chắc chắn có ai đó đã để cửa mở.","fa":"حتماً یک نفر در را باز گذاشته است."},{"de":"Wenn irgendjemand fragt, sag, ich bin nicht da.","en":"If anyone asks, say I'm not here.","ru":"Если кто-нибудь спросит, скажи, что меня нет.","vi":"Nếu có ai hỏi thì nói là tôi không có.","fa":"اگر کسی پرسید بگو من آنجا نیستم."}]},{"word":"irgendwann","en":"sometime, at some point","ru":"когда-нибудь, когда-то","vi":"tại một thời điểm nào đó","fa":"در یک نقطه","examples":[{"de":"Wir sollten uns irgendwann mal wieder treffen.","en":"We should meet up again sometime.","ru":"Нам стоит как-нибудь снова встретиться.","vi":"Chúng ta nên gặp lại nhau lúc nào đó.","fa":"ما باید یک بار دیگر ملاقات کنیم."},{"de":"Irgendwann wirst du es verstehen.","en":"At some point you'll understand it.","ru":"Когда-нибудь ты это поймёшь.","vi":"Đến một lúc nào đó bạn sẽ hiểu.","fa":"یه وقتایی متوجه میشی"},{"de":"Er kommt irgendwann am Nachmittag.","en":"He's coming sometime in the afternoon.","ru":"Он придёт где-то во второй половине дня.","vi":"Anh ấy sẽ đến vào lúc nào đó vào buổi chiều.","fa":"او یک روز بعد از ظهر می آید."}]},{"word":"irgendwo","en":"somewhere, anywhere","ru":"где-нибудь, где-то","vi":"ở đâu đó","fa":"جایی","examples":[{"de":"Mein Handy muss irgendwo hier liegen.","en":"My phone must be lying around here somewhere.","ru":"Мой телефон должен валяться где-то здесь.","vi":"Điện thoại di động của tôi chắc phải ở đâu đó ở đây.","fa":"تلفن همراه من باید جایی باشد."},{"de":"Lass uns irgendwo etwas essen.","en":"Let's go and eat somewhere.","ru":"Давай поедим где-нибудь.","vi":"Hãy ăn gì đó ở đâu đó.","fa":"یه جایی یه چیزی بخوریم"},{"de":"Hast du den Schlüssel irgendwo gesehen?","en":"Have you seen the key anywhere?","ru":"Ты где-нибудь видел ключ?","vi":"Bạn có thấy chìa khóa ở đâu không?","fa":"آیا کلید را جایی دیده اید؟"}]},{"word":"irren","en":"to be mistaken, to err","ru":"ошибаться, заблуждаться","vi":"lỗi","fa":"اشتباه کن","examples":[{"de":"Da musst du dich irren, das war ganz anders.","en":"You must be mistaken there, it was quite different.","ru":"Тут ты, должно быть, ошибаешься, всё было совсем иначе.","vi":"Chắc bạn nhầm rồi, chuyện đó hoàn toàn khác.","fa":"حتما اشتباه می کنید، این کاملا متفاوت بود."},{"de":"Jeder kann sich mal irren.","en":"Anyone can be wrong sometimes.","ru":"Каждый может иногда ошибиться.","vi":"Mọi người đôi khi có thể sai.","fa":"همه ممکن است گاهی اشتباه کنند."},{"de":"Wenn ich mich nicht irre, war das im Mai.","en":"If I'm not mistaken, that was in May.","ru":"Если я не ошибаюсь, это было в мае.","vi":"Nếu tôi không nhầm thì đó là vào tháng Năm.","fa":"اگر اشتباه نکنم اردیبهشت بود."}]},{"word":"Das ist eine gute Idee","en":"That's a good idea (accepting a suggestion)","ru":"Это хорошая идея (согласие с предложением)","vi":"Đó là một ý tưởng tốt","fa":"این ایده خوبی است","examples":[{"de":"Das ist eine gute Idee, machen wir das!","en":"That's a good idea, let's do it!","ru":"Это хорошая идея, давай так и сделаем!","vi":"Đó là một ý tưởng hay, hãy thực hiện nó!","fa":"این ایده خوبی است، بیایید آن را انجام دهیم!"}]},{"word":"das ist mir Wurst","en":"I don't care / it's all the same to me (colloquial)","ru":"мне всё равно (разг.)","vi":"Tôi không quan tâm / với tôi tất cả đều như nhau","fa":"برام مهم نیست / برام یکیه","examples":[{"de":"Ob wir Pizza oder Pasta essen, das ist mir Wurst.","en":"Whether we eat pizza or pasta, I don't care.","ru":"Пиццу или пасту — мне всё равно.","vi":"Cho dù chúng ta ăn pizza hay mì ống, đối với tôi đó đều là xúc xích.","fa":"چه پیتزا بخوریم چه پاستا، این برای من سوسیس است."}]},{"word":"ja","en":"yes","ru":"да","vi":"vâng","fa":"بله","examples":[{"de":"Möchtest du einen Kaffee? – Ja, gerne.","en":"Would you like a coffee? – Yes, please.","ru":"Хочешь кофе? — Да, с удовольствием.","vi":"Bạn có muốn uống cà phê không? - Vâng, rất hân hạnh.","fa":"آیا قهوه میل دارید؟ - بله با کمال میل."},{"de":"Ja, ich komme morgen zur Party.","en":"Yes, I'm coming to the party tomorrow.","ru":"Да, я приду завтра на вечеринку.","vi":"Vâng, ngày mai tôi sẽ đến bữa tiệc.","fa":"بله، فردا به مهمانی می آیم."}]},{"word":"Ja, gerne","en":"Yes, gladly (agreeing)","ru":"Да, с удовольствием (согласие)","vi":"Vâng, rất vui lòng","fa":"بله، با کمال میل","examples":[{"de":"Ja, gerne, ich helfe dir dabei.","en":"Yes, gladly, I'll help you with it.","ru":"Да, с удовольствием, я тебе помогу.","vi":"Vâng, tôi rất vui được giúp bạn việc đó.","fa":"بله، خوشحالم که در این زمینه به شما کمک می کنم."}]},{"word":"die Jacke","en":"jacket","ru":"куртка","vi":"áo khoác","fa":"ژاکت","examples":[{"de":"Zieh deine Jacke an, es ist kalt draußen.","en":"Put on your jacket, it's cold outside.","ru":"Надень куртку, на улице холодно.","vi":"Mặc áo khoác vào đi, ngoài trời lạnh lắm.","fa":"ژاکتت را بپوش، بیرون سرد است."},{"de":"Ich habe meine Jacke im Restaurant vergessen.","en":"I forgot my jacket at the restaurant.","ru":"Я забыл куртку в ресторане.","vi":"Tôi quên áo khoác ở nhà hàng.","fa":"کتم را در رستوران فراموش کردم."}]},{"word":"die Jause","en":"snack (Austrian)","ru":"перекус, полдник (австр.)","vi":"bữa ăn nhẹ","fa":"میان وعده","examples":[{"de":"Die Kinder essen um zehn Uhr eine kleine Jause in der Schule.","en":"The children have a small snack at ten o'clock at school.","ru":"Дети перекусывают в десять часов в школе.","vi":"Bọn trẻ ăn một bữa ăn nhẹ ở trường lúc mười giờ.","fa":"بچه ها ساعت ده یک میان وعده کوچک در مدرسه می خورند."},{"de":"Zur Jause gibt es Brot mit Käse und Äpfel.","en":"For the snack there is bread with cheese and apples.","ru":"На перекус — хлеб с сыром и яблоки.","vi":"Đối với đồ ăn nhẹ có bánh mì với pho mát và táo.","fa":"برای میان وعده ها نان با پنیر و سیب وجود دارد."}]},{"word":"jdm","en":"(abbreviation) to/for someone (dative of 'jemand')","ru":"(сокращение) кому-либо (дательный падеж от «jemand»)","vi":"smb","fa":"smb","examples":[{"de":"jdm helfen heißt, jemandem zu helfen.","en":"'jdm helfen' means to help someone.","ru":"«jdm helfen» означает «помочь кому-либо».","vi":"to help sb có nghĩa là giúp đỡ ai đó.","fa":"کمک کردن sb به معنای کمک کردن به کسی است."},{"de":"Im Wörterbuch steht 'jdm etwas geben'.","en":"The dictionary says 'jdm etwas geben' (to give someone something).","ru":"В словаре написано «jdm etwas geben» (дать кому-либо что-либо).","vi":"Từ điển nói 'đưa cái gì đó cho ai đó'.","fa":"فرهنگ لغت می گوید \"چیزی به sb دادن\"."},{"de":"Die Abkürzung jdm steht für 'jemandem'.","en":"The abbreviation 'jdm' stands for 'jemandem'.","ru":"Сокращение «jdm» означает «jemandem».","vi":"Chữ viết tắt jdm là viết tắt của 'ai đó'.","fa":"مخفف jdm مخفف 'someone' است."}]},{"word":"je","en":"each, per; ever","ru":"каждый, по; когда-либо","vi":"bao giờ hết","fa":"همیشه","examples":[{"de":"Die Karten kosten je zehn Euro.","en":"The tickets cost ten euros each.","ru":"Билеты стоят по десять евро каждый.","vi":"Các thẻ có giá mười euro mỗi thẻ.","fa":"قیمت هر کارت ده یورو است."},{"de":"Hast du je daran gedacht, ins Ausland zu ziehen?","en":"Have you ever thought about moving abroad?","ru":"Ты когда-нибудь думал о переезде за границу?","vi":"Bạn đã bao giờ nghĩ đến việc chuyển ra nước ngoài chưa?","fa":"آیا تا به حال به مهاجرت به خارج از کشور فکر کرده اید؟"}]},{"word":"je nachdem","en":"depending (on)","ru":"в зависимости (от)","vi":"tùy theo","fa":"بسته به","examples":[{"de":"Je nachdem, wie das Wetter ist, gehen wir wandern oder nicht.","en":"Depending on the weather, we'll go hiking or not.","ru":"В зависимости от погоды, мы пойдём в поход или нет.","vi":"Tùy thuộc vào thời tiết như thế nào mà chúng ta có đi leo núi hay không.","fa":"بسته به اینکه آب و هوا چگونه باشد، پیاده روی می کنیم یا نه."},{"de":"Der Preis ändert sich je nachdem, wie viel du bestellst.","en":"The price changes depending on how much you order.","ru":"Цена меняется в зависимости от того, сколько ты заказываешь.","vi":"Giá thay đổi tùy theo số lượng bạn đặt hàng.","fa":"قیمت بسته به مقدار سفارش شما تغییر می کند."}]},{"word":"die Jeans","en":"jeans","ru":"джинсы","vi":"quần jean","fa":"شلوار جین","examples":[{"de":"Ich trage fast jeden Tag eine Jeans.","en":"I wear jeans almost every day.","ru":"Я почти каждый день ношу джинсы.","vi":"Tôi mặc quần jean hầu như mỗi ngày.","fa":"من تقریبا هر روز شلوار جین می پوشم."},{"de":"Diese Jeans ist mir zu lang.","en":"These jeans are too long for me.","ru":"Эти джинсы мне слишком длинные.","vi":"Những chiếc quần jean này quá dài đối với tôi.","fa":"این شلوار جین برای من خیلی بلند است."}]},{"word":"jeder","en":"every, each","ru":"каждый","vi":"mọi người","fa":"همه","examples":[{"de":"Jeder Schüler muss die Hausaufgaben machen.","en":"Every student has to do the homework.","ru":"Каждый ученик должен делать домашнее задание.","vi":"Mỗi học sinh đều phải làm bài tập về nhà.","fa":"هر دانش آموزی باید تکالیف خود را انجام دهد."},{"de":"Jeder kann Fehler machen.","en":"Everyone can make mistakes.","ru":"Каждый может совершать ошибки.","vi":"Mọi người đều có thể phạm sai lầm.","fa":"همه ممکن است اشتباه کنند."}]},{"word":"jederzeit","en":"at any time, anytime","ru":"в любое время, всегда","vi":"bất cứ lúc nào","fa":"در هر زمان","examples":[{"de":"Du kannst mich jederzeit anrufen.","en":"You can call me at any time.","ru":"Ты можешь звонить мне в любое время.","vi":"Bạn có thể gọi cho tôi bất cứ lúc nào.","fa":"هرزمان خواستید می توانید با من تماس بگیرید."},{"de":"Wir sind jederzeit für dich da.","en":"We're there for you anytime.","ru":"Мы всегда рядом с тобой.","vi":"Chúng tôi luôn ở đó vì bạn.","fa":"ما همیشه در کنار شما هستیم."},{"de":"Der Laden ist jederzeit gut besucht.","en":"The shop is busy at all times.","ru":"В магазине всё время много народу.","vi":"Cửa hàng luôn bận rộn.","fa":"فروشگاه همیشه شلوغ است."}]},{"word":"jedes Mal","en":"every time, each time","ru":"каждый раз","vi":"mọi lúc","fa":"هر بار","examples":[{"de":"Jedes Mal, wenn er kommt, regnet es.","en":"Every time he comes, it rains.","ru":"Каждый раз, когда он приходит, идёт дождь.","vi":"Lần nào anh về cũng mưa.","fa":"هر بار که می آید باران می بارد."},{"de":"Sie lacht jedes Mal über denselben Witz.","en":"She laughs at the same joke every time.","ru":"Она каждый раз смеётся над одной и той же шуткой.","vi":"Lần nào cô ấy cũng cười vì cùng một trò đùa.","fa":"او هر بار به همان شوخی می خندد."},{"de":"Jedes Mal vergesse ich meinen Regenschirm.","en":"Every time I forget my umbrella.","ru":"Каждый раз я забываю зонт.","vi":"Mỗi lần tôi quên ô.","fa":"هر بار که چترم را فراموش می کنم."}]},{"word":"jedoch","en":"however","ru":"однако","vi":"tuy nhiên","fa":"با این حال","examples":[{"de":"Das Restaurant ist teuer, jedoch ist das Essen sehr gut.","en":"The restaurant is expensive, however the food is very good.","ru":"Ресторан дорогой, однако еда очень хорошая.","vi":"Nhà hàng đắt tiền nhưng đồ ăn rất ngon.","fa":"رستوران گران است، اما غذا بسیار خوب است."},{"de":"Ich wollte kommen, jedoch hatte ich keine Zeit.","en":"I wanted to come, however I had no time.","ru":"Я хотел прийти, однако у меня не было времени.","vi":"Ich wollte kommen, jedoch hatte ich keine Zeit.","fa":"می خواستم بیام ولی وقت نکردم."}]},{"word":"jemals","en":"ever","ru":"когда-либо","vi":"bao giờ hết","fa":"همیشه","examples":[{"de":"Warst du jemals in Japan?","en":"Have you ever been to Japan?","ru":"Ты когда-нибудь был в Японии?","vi":"Have you ever been to Japan?","fa":"آیا تا به حال به ژاپن رفته اید؟"},{"de":"Ich habe so etwas noch nie jemals erlebt.","en":"I have never experienced anything like that.","ru":"Я никогда в жизни не переживал ничего подобного.","vi":"Tôi chưa bao giờ trải nghiệm bất cứ điều gì như thế này trước đây.","fa":"من قبلاً چنین چیزی را تجربه نکرده بودم."}]},{"word":"jemand","en":"someone","ru":"кто-то","vi":"ai đó","fa":"کسی","examples":[{"de":"Hat jemand meinen Regenschirm gesehen?","en":"Has anyone seen my umbrella?","ru":"Кто-нибудь видел мой зонт?","vi":"Có ai nhìn thấy chiếc ô của tôi không?","fa":"کسی چتر من را دیده است؟"},{"de":"Es klopft jemand an der Tür.","en":"Someone is knocking on the door.","ru":"Кто-то стучит в дверь.","vi":"Có người gõ cửa.","fa":"یک نفر در را می زند."}]},{"word":"jemandem auf die Nerven gehen","en":"to get on someone's nerves","ru":"действовать кому-то на нервы","vi":"làm ai đó lo lắng","fa":"اعصاب کسی رو خورد کردن","examples":[{"de":"Der laute Nachbar geht mir echt auf die Nerven.","en":"The loud neighbour really gets on my nerves.","ru":"Шумный сосед реально действует мне на нервы.","vi":"Người hàng xóm ồn ào thực sự làm tôi khó chịu.","fa":"همسایه پر سر و صدا واقعاً اعصابم را خرد می کند."}]},{"word":"jemandem das Wasser reichen können","en":"to be able to hold a candle to someone (usually negated)","ru":"годиться в подмётки (обычно с отрицанием)","vi":"có thể cầm nến cho ai đó","fa":"بتوانی شمع را برای کسی نگه دارم","examples":[{"de":"Beim Kochen kann ihr niemand das Wasser reichen.","en":"When it comes to cooking, no one can hold a candle to her.","ru":"В готовке ей никто в подмётки не годится.","vi":"Về nấu ăn thì không ai có thể sánh bằng cô ấy.","fa":"وقتی صحبت از آشپزی می شود، هیچ کس نمی تواند با او برابری کند."}]},{"word":"jemandem die kalte Schulter zeigen","en":"to give someone the cold shoulder","ru":"демонстративно игнорировать кого-то","vi":"trao cho ai đó một bờ vai lạnh lùng","fa":"دادن شانه سرد به کسی","examples":[{"de":"Seit dem Streit zeigt sie ihm die kalte Schulter.","en":"Since the argument she's been giving him the cold shoulder.","ru":"После ссоры она демонстративно его игнорирует.","vi":"Cô ấy đã tỏ ra lạnh lùng với anh ấy kể từ cuộc tranh cãi.","fa":"او از زمان مشاجره او را سرد می کند."}]},{"word":"jemandem ein Bein stellen","en":"to trip someone up (literally or figuratively)","ru":"подставить подножку кому-то","vi":"vấp phải ai đó","fa":"به زمین زدن کسی","examples":[{"de":"Im Job hat ihm ein Kollege ein Bein gestellt.","en":"At work a colleague tripped him up.","ru":"На работе коллега подставил ему подножку.","vi":"Một đồng nghiệp đã vấp ngã anh ta tại nơi làm việc.","fa":"یکی از همکاران او را در محل کار زمین انداخت."}]},{"word":"jemandem einen Bären aufbinden","en":"to pull someone's leg / tell a tall tale","ru":"вешать лапшу на уши, дурачить","vi":"kéo chân ai/kể một câu chuyện hoang đường","fa":"کشیدن پای کسی / قصه بلند گفتن","examples":[{"de":"Das glaube ich nicht — du willst mir einen Bären aufbinden!","en":"I don't believe that — you're pulling my leg!","ru":"Не верю — ты вешаешь мне лапшу на уши!","vi":"Tôi không tin điều đó - bạn muốn trói một con gấu vào người tôi!","fa":"من این را باور نمی کنم - می خواهید یک خرس را روی من ببندید!"}]},{"word":"jemandem etwas durch die Blume sagen","en":"to say something indirectly / hint at it","ru":"сказать что-то намёком, обиняками","vi":"nói điều gì đó một cách gián tiếp/ gợi ý về nó","fa":"چیزی را غیرمستقیم گفتن / به آن اشاره کرد","examples":[{"de":"Sie hat ihm durch die Blume gesagt, dass sie keine Zeit hat.","en":"She hinted to him that she has no time.","ru":"Она намёком дала ему понять, что у неё нет времени.","vi":"Cô nói với anh qua bông hoa rằng cô không có thời gian.","fa":"او از طریق گل به او گفت که وقت ندارد."}]},{"word":"jemandem Honig um den Mund schmieren","en":"to butter someone up / flatter","ru":"льстить, умасливать кого-то","vi":"tán tỉnh/tâng bốc ai đó","fa":"کره کردن / چاپلوسی کردن به کسی","examples":[{"de":"Er schmiert dem Chef Honig um den Mund, um befördert zu werden.","en":"He butters up the boss to get promoted.","ru":"Он льстит начальнику, чтобы получить повышение.","vi":"Anh ta ve vãn ông chủ để được thăng chức.","fa":"او برای اینکه ترفیع بگیرد، رئیس را زیر و رو می کند."}]},{"word":"jemandem reinen Wein einschenken","en":"to tell someone the plain truth","ru":"сказать кому-то всю правду","vi":"nói với ai đó sự thật rõ ràng","fa":"برای گفتن حقیقت آشکار به کسی","examples":[{"de":"Ich muss dir reinen Wein einschenken: Es hat nicht geklappt.","en":"I have to be honest with you: it didn't work out.","ru":"Скажу тебе всю правду: не получилось.","vi":"Tôi phải đưa cho bạn rượu nguyên chất: nó không có tác dụng.","fa":"باید به شما شراب خالص بدهم: کار نکرد."}]},{"word":"jemanden auf die Palme bringen","en":"to drive someone up the wall","ru":"выводить кого-то из себя","vi":"đẩy ai đó lên tường","fa":"راندن کسی از دیوار","examples":[{"de":"Seine Ausreden bringen mich auf die Palme.","en":"His excuses drive me up the wall.","ru":"Его отговорки выводят меня из себя.","vi":"Những lời bào chữa của anh ấy làm tôi khó chịu.","fa":"بهانه های او مرا آزار می دهد."}]},{"word":"jemanden erschrecken","en":"to frighten, startle someone","ru":"пугать кого-либо","vi":"dọa ai đó","fa":"کسی را بترساند","examples":[{"de":"Er wollte seine Schwester mit der Maske erschrecken.","en":"He wanted to scare his sister with the mask.","ru":"Он хотел напугать сестру маской.","vi":"Anh muốn dọa em gái mình bằng chiếc mặt nạ.","fa":"می خواست با ماسک خواهرش را بترساند."},{"de":"Die laute Explosion im Film erschreckte alle Zuschauer.","en":"The loud explosion in the movie frightened all the viewers.","ru":"Громкий взрыв в фильме напугал всех зрителей.","vi":"Tiếng nổ lớn trong phim khiến mọi người xem sợ hãi.","fa":"انفجار شدید در فیلم همه تماشاگران را ترساند."}]},{"word":"jemanden im Stich lassen","en":"to leave someone in the lurch","ru":"бросить кого-то в беде","vi":"để lại ai đó trong tình trạng chao đảo","fa":"کسی را در بیراهه گذاشتن","examples":[{"de":"Ein guter Freund lässt dich nicht im Stich.","en":"A good friend doesn't leave you in the lurch.","ru":"Хороший друг не бросит тебя в беде.","vi":"Một người bạn tốt sẽ không làm bạn thất vọng.","fa":"یک دوست خوب شما را ناامید نمی کند."}]},{"word":"jetzt","en":"now","ru":"сейчас","vi":"bây giờ","fa":"اکنون","examples":[{"de":"Ich muss jetzt los, sonst komme ich zu spät.","en":"I have to leave now, otherwise I'll be late.","ru":"Мне нужно идти сейчас, иначе я опоздаю.","vi":"Tôi phải đi bây giờ, nếu không tôi sẽ muộn mất.","fa":"الان باید برم وگرنه دیر میرسم."},{"de":"Jetzt verstehe ich endlich, wie das funktioniert.","en":"Now I finally understand how that works.","ru":"Теперь я наконец понимаю, как это работает.","vi":"Now I finally understand how this works.","fa":"حالا بالاخره می فهمم که این چطور کار می کند."}]},{"word":"jeweils","en":"respectively, each time","ru":"соответственно, каждый раз","vi":"mỗi","fa":"هر کدام","examples":[{"de":"Die Gruppen bestehen jeweils aus fünf Personen.","en":"The groups each consist of five people.","ru":"Каждая группа состоит из пяти человек.","vi":"Mỗi nhóm gồm có năm người.","fa":"هر گروه از پنج نفر تشکیل شده است."},{"de":"Der Kurs findet jeweils am Montag und Mittwoch statt.","en":"The course takes place respectively on Monday and Wednesday.","ru":"Курс проходит соответственно по понедельникам и средам.","vi":"Khóa học diễn ra vào thứ Hai và thứ Tư.","fa":"این دوره در روزهای دوشنبه و چهارشنبه برگزار می شود."}]},{"word":"der Journalist","en":"journalist","ru":"журналист","vi":"nhà báo","fa":"روزنامه نگار","examples":[{"de":"Der Journalist schreibt einen Artikel über die Wahlen.","en":"The journalist is writing an article about the elections.","ru":"Журналист пишет статью о выборах.","vi":"Nhà báo đang viết một bài báo về cuộc bầu cử.","fa":"روزنامه نگار در حال نوشتن مقاله ای درباره انتخابات است."},{"de":"Sie möchte Journalistin werden und für eine Zeitung arbeiten.","en":"She wants to become a journalist and work for a newspaper.","ru":"Она хочет стать журналисткой и работать в газете.","vi":"Cô muốn trở thành một nhà báo và làm việc cho một tờ báo.","fa":"او می خواهد روزنامه نگار شود و در روزنامه کار کند."}]},{"word":"die Journalistin","en":"journalist (female)","ru":"журналистка","vi":"nhà báo","fa":"روزنامه نگار","examples":[{"de":"Die Journalistin berichtete live von der Demonstration.","en":"The journalist reported live from the demonstration.","ru":"Журналистка вела репортаж с демонстрации в прямом эфире.","vi":"Nhà báo đưa tin trực tiếp về cuộc biểu tình.","fa":"این روزنامه نگار به صورت زنده از تظاهرات گزارش داد."},{"de":"Als Journalistin interviewt sie oft bekannte Politiker.","en":"As a journalist she often interviews well-known politicians.","ru":"Как журналистка она часто берёт интервью у известных политиков.","vi":"Là một nhà báo, cô thường phỏng vấn các chính trị gia nổi tiếng.","fa":"او به عنوان یک روزنامه نگار اغلب با سیاستمداران مشهور مصاحبه می کند."},{"de":"Die Journalistin bekam einen Preis für ihren Bericht.","en":"The journalist received an award for her report.","ru":"Журналистка получила премию за свой репортаж.","vi":"Nhà báo đã nhận được giải thưởng cho bài báo của mình.","fa":"این روزنامه نگار برای گزارش خود جایزه دریافت کرد."}]},{"word":"der Judoanzug","en":"judo suit, judogi","ru":"костюм для дзюдо (дзюдоги)","vi":"bộ đồ judo","fa":"لباس جودو","examples":[{"de":"Vor dem Training zieht er seinen weißen Judoanzug an.","en":"Before training he puts on his white judo suit.","ru":"Перед тренировкой он надевает свой белый костюм для дзюдо.","vi":"Trước khi tập luyện, anh ấy mặc bộ đồ judo màu trắng.","fa":"او قبل از تمرین لباس سفید جودوی خود را می پوشد."},{"de":"Mein Judoanzug ist nach dem Waschen wieder ganz sauber.","en":"My judo suit is completely clean again after washing.","ru":"Мой костюм для дзюдо после стирки снова совсем чистый.","vi":"Bộ đồ judo của tôi lại hoàn toàn sạch sẽ sau khi giặt.","fa":"کت و شلوار جودو من بعد از شستن دوباره کاملا تمیز می شود."},{"de":"Der neue Judoanzug ist mir an den Ärmeln zu lang.","en":"The new judo suit is too long for me at the sleeves.","ru":"Новый костюм для дзюдо мне длинноват в рукавах.","vi":"Tay áo của bộ đồ judo mới quá dài đối với tôi.","fa":"آستین های لباس جودوی جدید برای من خیلی بلند است."}]},{"word":"die Jugend","en":"youth","ru":"молодость, юность","vi":"tuổi trẻ","fa":"جوانان","examples":[{"de":"Er hat seine Jugend auf dem Land verbracht.","en":"He spent his youth in the countryside.","ru":"Он провёл свою юность в деревне.","vi":"Anh đã trải qua tuổi trẻ của mình ở quê hương.","fa":"دوران جوانی خود را در کشور گذراند."},{"de":"Die Jugend von heute nutzt viel das Internet.","en":"Today's youth use the internet a lot.","ru":"Сегодняшняя молодёжь много пользуется интернетом.","vi":"Giới trẻ ngày nay sử dụng Internet rất nhiều.","fa":"جوانان امروزی زیاد از اینترنت استفاده می کنند."}]},{"word":"die Jugendherberge","en":"youth hostel","ru":"молодёжное общежитие, хостел","vi":"ký túc xá thanh niên","fa":"خوابگاه جوانان","examples":[{"de":"Wir haben in einer Jugendherberge übernachtet, weil sie günstig ist.","en":"We stayed in a youth hostel because it's cheap.","ru":"Мы ночевали в молодёжном хостеле, потому что это дёшево.","vi":"Chúng tôi ở trong một ký túc xá thanh niên vì nó rẻ.","fa":"ما در خوابگاه جوانان ماندیم چون ارزان بود."},{"de":"Die Jugendherberge liegt nur fünf Minuten vom Bahnhof entfernt.","en":"The youth hostel is only five minutes from the train station.","ru":"Молодёжный хостел находится всего в пяти минутах от вокзала.","vi":"Ký túc xá thanh niên chỉ cách ga xe lửa năm phút.","fa":"خوابگاه جوانان تنها پنج دقیقه با ایستگاه قطار فاصله دارد."}]},{"word":"der Jugendliche","en":"young person, teenager","ru":"подросток","vi":"người trẻ","fa":"فرد جوان","examples":[{"de":"Viele Jugendliche treffen sich am Wochenende im Park.","en":"Many young people meet in the park on weekends.","ru":"Многие подростки встречаются по выходным в парке.","vi":"Nhiều bạn trẻ gặp nhau ở công viên vào cuối tuần.","fa":"بسیاری از جوانان در تعطیلات آخر هفته در پارک ملاقات می کنند."},{"de":"Der Film ist besonders bei Jugendlichen beliebt.","en":"The film is especially popular among young people.","ru":"Фильм особенно популярен среди подростков.","vi":"Bộ phim đặc biệt được giới trẻ yêu thích.","fa":"این فیلم در بین جوانان محبوبیت خاصی دارد."}]},{"word":"jung","en":"young","ru":"молодой","vi":"trẻ","fa":"جوان","examples":[{"de":"Die jungen Leute tanzen gern auf Partys.","en":"Young people like to dance at parties.","ru":"Молодые люди любят танцевать на вечеринках.","vi":"Giới trẻ thích khiêu vũ trong các bữa tiệc.","fa":"جوانان دوست دارند در مهمانی ها برقصند."},{"de":"Meine Oma sieht für ihr Alter noch sehr jung aus.","en":"My grandma still looks very young for her age.","ru":"Моя бабушка выглядит очень молодо для своего возраста.","vi":"Bà tôi trông vẫn còn rất trẻ so với tuổi của bà.","fa":"مادربزرگ من نسبت به سنش هنوز خیلی جوان به نظر می رسد."}]},{"word":"der Junge","en":"boy","ru":"мальчик","vi":"cậu bé","fa":"پسر","examples":[{"de":"Der kleine Junge spielt im Garten mit seinem Hund.","en":"The little boy is playing in the garden with his dog.","ru":"Маленький мальчик играет в саду со своей собакой.","vi":"Cậu bé chơi trong vườn với con chó của mình.","fa":"پسر کوچک با سگش در باغ بازی می کند."},{"de":"In der Klasse sind zehn Jungen und zwölf Mädchen.","en":"There are ten boys and twelve girls in the class.","ru":"В классе десять мальчиков и двенадцать девочек.","vi":"Lớp có mười nam và mười hai nữ.","fa":"در کلاس ده پسر و دوازده دختر وجود دارد."}]},{"word":"das Kabel","en":"cable","ru":"кабель, провод","vi":"cáp","fa":"کابل","examples":[{"de":"Das Kabel für den Laptop ist zu kurz.","en":"The cable for the laptop is too short.","ru":"Кабель для ноутбука слишком короткий.","vi":"Cáp cho máy tính xách tay quá ngắn.","fa":"کابل لپ تاپ خیلی کوتاه است."},{"de":"Bitte schließen Sie das Kabel an den Fernseher an.","en":"Please connect the cable to the television.","ru":"Пожалуйста, подключите кабель к телевизору.","vi":"Vui lòng kết nối cáp với TV.","fa":"لطفا کابل را به تلویزیون وصل کنید."}]},{"word":"die Kabine","en":"cabin, booth","ru":"кабина, каюта","vi":"cabin","fa":"کابین","examples":[{"de":"Die Kabine im Schiff war klein, aber gemütlich.","en":"The cabin on the ship was small but cozy.","ru":"Каюта на корабле была маленькой, но уютной.","vi":"Cabin trên tàu nhỏ nhưng tiện nghi.","fa":"کابین کشتی کوچک اما راحت بود."},{"de":"Sie probierte das Kleid in der Kabine an.","en":"She tried on the dress in the fitting room.","ru":"Она примерила платье в примерочной кабине.","vi":"Cô thử chiếc váy trong cabin.","fa":"او لباس را در کابین امتحان کرد."}]},{"word":"der Kaffee","en":"coffee","ru":"кофе","vi":"cà phê","fa":"قهوه","examples":[{"de":"Ich trinke jeden Morgen eine Tasse Kaffee.","en":"I drink a cup of coffee every morning.","ru":"Я каждое утро пью чашку кофе.","vi":"Tôi uống một tách cà phê vào mỗi buổi sáng.","fa":"من هر روز صبح یک فنجان قهوه می نوشم."},{"de":"Möchtest du einen Kaffee mit Milch?","en":"Would you like a coffee with milk?","ru":"Хочешь кофе с молоком?","vi":"Bạn có muốn uống cà phê với sữa không?","fa":"آیا می خواهید یک قهوه با شیر بخورید؟"}]},{"word":"das Kaffeehaus","en":"coffeehouse, café","ru":"кофейня","vi":"quán cà phê","fa":"قهوه خانه","examples":[{"de":"In Wien gibt es viele traditionelle Kaffeehäuser.","en":"In Vienna there are many traditional coffeehouses.","ru":"В Вене много традиционных кофеен.","vi":"Có rất nhiều quán cà phê truyền thống ở Vienna.","fa":"قهوه خانه های سنتی زیادی در وین وجود دارد."},{"de":"Wir treffen uns im Kaffeehaus um die Ecke.","en":"We're meeting at the coffeehouse around the corner.","ru":"Мы встречаемся в кофейне за углом.","vi":"Chúng ta sẽ gặp nhau ở quán cà phê ở góc phố.","fa":"در قهوه خانه اطراف همدیگر را خواهیم دید."}]},{"word":"der Kaiser","en":"emperor","ru":"император, кайзер","vi":"hoàng đế","fa":"امپراتور","examples":[{"de":"Der Kaiser regierte das Reich über vierzig Jahre.","en":"The emperor ruled the empire for over forty years.","ru":"Император правил империей более сорока лет.","vi":"Hoàng đế cai trị đế quốc trong bốn mươi năm.","fa":"امپراتور به مدت چهل سال بر امپراتوری حکومت کرد."},{"de":"Der römische Kaiser ließ riesige Bauten errichten.","en":"The Roman emperor had huge buildings erected.","ru":"Римский император велел возводить огромные сооружения.","vi":"Hoàng đế La Mã đã xây dựng những tòa nhà khổng lồ.","fa":"امپراتور روم ساختمان های عظیمی ساخته بود."},{"de":"Nach der Revolution musste der Kaiser abdanken.","en":"After the revolution the emperor had to abdicate.","ru":"После революции императору пришлось отречься от престола.","vi":"Sau cuộc cách mạng, hoàng đế phải thoái vị.","fa":"پس از انقلاب، امپراتور مجبور به کناره گیری شد."}]},{"word":"der Kakao","en":"cocoa","ru":"какао","vi":"ca cao","fa":"کاکائو","examples":[{"de":"Die Kinder trinken gern heißen Kakao im Winter.","en":"Children like to drink hot cocoa in winter.","ru":"Дети любят пить горячее какао зимой.","vi":"Trẻ em thích uống ca cao nóng vào mùa đông.","fa":"بچه ها دوست دارند در زمستان کاکائو داغ بنوشند."},{"de":"Für den Kuchen brauchen wir zwei Löffel Kakao.","en":"For the cake we need two spoons of cocoa.","ru":"Для торта нам нужны две ложки какао.","vi":"Đối với chiếc bánh chúng ta cần hai thìa ca cao.","fa":"برای کیک به دو قاشق کاکائو نیاز داریم."}]},{"word":"der Kalender","en":"calendar","ru":"календарь","vi":"lịch","fa":"تقویم","examples":[{"de":"Ich habe den Termin schon in meinen Kalender eingetragen.","en":"I've already entered the appointment in my calendar.","ru":"Я уже внёс встречу в свой календарь.","vi":"Tôi đã nhập cuộc hẹn vào lịch của mình rồi.","fa":"من قبلاً قرار ملاقات را در تقویم خود وارد کرده ام."},{"de":"An der Wand hängt ein Kalender mit Fotos von Bergen.","en":"There is a calendar with photos of mountains hanging on the wall.","ru":"На стене висит календарь с фотографиями гор.","vi":"Có một cuốn lịch có hình ảnh những ngọn núi trên tường.","fa":"یک تقویم با عکس های کوه روی دیوار وجود دارد."}]},{"word":"die Kalorie","en":"calorie","ru":"калория","vi":"lượng calo","fa":"کالری","examples":[{"de":"Schokolade hat sehr viele Kalorien.","en":"Chocolate has a great many calories.","ru":"В шоколаде очень много калорий.","vi":"Sô cô la có rất nhiều calo.","fa":"شکلات کالری زیادی دارد."},{"de":"Ich zähle seit einer Woche meine Kalorien.","en":"I have been counting my calories for a week.","ru":"Уже неделю я считаю свои калории.","vi":"Tôi đã đếm lượng calo của mình trong một tuần.","fa":"من یک هفته است که کالری هایم را می شمارم."},{"de":"Diese Suppe hat nur wenige Kalorien.","en":"This soup has only a few calories.","ru":"В этом супе всего немного калорий.","vi":"Món súp này có ít calo.","fa":"این سوپ کالری کمی دارد."}]},{"word":"kalorienarm","en":"low-calorie","ru":"низкокалорийный","vi":"ít calo","fa":"کم کالری","examples":[{"de":"Salat ist eine kalorienarme Mahlzeit.","en":"Salad is a low-calorie meal.","ru":"Салат — это низкокалорийное блюдо.","vi":"Salad là một bữa ăn ít calo.","fa":"سالاد یک وعده غذایی کم کالری است."},{"de":"Ich achte auf kalorienarme Ernährung.","en":"I pay attention to a low-calorie diet.","ru":"Я слежу за низкокалорийным питанием.","vi":"Tôi chú ý đến chế độ ăn ít calo.","fa":"من به رژیم کم کالری توجه می کنم."},{"de":"Dieses Getränk ist besonders kalorienarm.","en":"This drink is especially low in calories.","ru":"Этот напиток особенно низкокалорийный.","vi":"Thức uống này đặc biệt ít calo.","fa":"این نوشیدنی به خصوص کم کالری است."}]},{"word":"kalt","en":"cold","ru":"холодный","vi":"lạnh","fa":"سرد","examples":[{"de":"Heute ist es sehr kalt, du solltest dich warm anziehen.","en":"It's very cold today, you should dress warmly.","ru":"Сегодня очень холодно, тебе стоит тепло одеться.","vi":"Hôm nay trời rất lạnh, các bạn nhớ mặc ấm nhé.","fa":"امروز هوا خیلی سرده، باید لباس گرم بپوشی."},{"de":"Die Suppe ist schon kalt geworden.","en":"The soup has already gone cold.","ru":"Суп уже остыл.","vi":"Súp đã nguội rồi.","fa":"سوپ از قبل سرد شده است."}]},{"word":"die Kamera","en":"camera","ru":"камера, фотоаппарат","vi":"máy ảnh","fa":"دوربین","examples":[{"de":"Er hat seine Kamera mit in den Urlaub genommen.","en":"He took his camera with him on vacation.","ru":"Он взял с собой камеру в отпуск.","vi":"Anh ấy mang theo máy ảnh trong kỳ nghỉ.","fa":"او در تعطیلات دوربینش را با خود برد."},{"de":"Mit dieser Kamera kann man auch Videos machen.","en":"With this camera you can also make videos.","ru":"Этой камерой можно также снимать видео.","vi":"Bạn cũng có thể tạo video bằng máy ảnh này.","fa":"همچنین می توانید با این دوربین فیلم بسازید."}]},{"word":"kämpfen","en":"to fight","ru":"бороться","vi":"chiến đấu","fa":"مبارزه کن","examples":[{"de":"Die Feuerwehrleute kämpften stundenlang gegen das Feuer.","en":"The firefighters fought against the fire for hours.","ru":"Пожарные часами боролись с огнём.","vi":"Lính cứu hỏa đã chiến đấu với ngọn lửa trong nhiều giờ.","fa":"آتش نشانان ساعت ها با آتش مبارزه کردند."},{"de":"Sie kämpft für gleiche Rechte für alle Menschen.","en":"She fights for equal rights for all people.","ru":"Она борется за равные права для всех людей.","vi":"Cô đấu tranh cho quyền bình đẳng cho tất cả mọi người.","fa":"او برای حقوق برابر برای همه مردم مبارزه می کند."}]},{"word":"der Kanal","en":"canal, channel","ru":"канал","vi":"kênh","fa":"کانال","examples":[{"de":"Das Boot fährt langsam durch den Kanal.","en":"The boat slowly moves through the canal.","ru":"Лодка медленно движется по каналу.","vi":"Thuyền di chuyển chậm rãi qua kênh.","fa":"قایق به آرامی در کانال حرکت می کند."},{"de":"Welchen Fernsehkanal siehst du am liebsten?","en":"Which TV channel do you like watching most?","ru":"Какой телеканал ты больше всего любишь смотреть?","vi":"Bạn thích xem kênh truyền hình nào nhất?","fa":"کدام کانال تلویزیونی را بیشتر دوست دارید؟"}]},{"word":"der Kandidat","en":"candidate","ru":"кандидат","vi":"ứng cử viên","fa":"نامزد","examples":[{"de":"Drei Kandidaten bewerben sich um die Stelle.","en":"Three candidates are applying for the position.","ru":"На эту должность претендуют три кандидата.","vi":"Ba ứng viên ứng tuyển vào vị trí này.","fa":"سه نامزد برای این موقعیت درخواست می کنند."},{"de":"Der Kandidat hat die Wahl klar gewonnen.","en":"The candidate clearly won the election.","ru":"Кандидат явно выиграл выборы.","vi":"Ứng cử viên rõ ràng đã thắng cử.","fa":"نامزد به وضوح در انتخابات پیروز شد."}]},{"word":"die Kanne","en":"pot, jug","ru":"чайник, кувшин","vi":"cái nồi","fa":"گلدان","examples":[{"de":"Sie stellte eine Kanne Tee auf den Tisch.","en":"She put a pot of tea on the table.","ru":"Она поставила чайник с чаем на стол.","vi":"Cô đặt bình trà lên bàn.","fa":"یک قابلمه چای روی میز گذاشت."},{"de":"Die Kanne ist voll mit frischem Kaffee.","en":"The pot is full of fresh coffee.","ru":"Кофейник полон свежего кофе.","vi":"Chiếc bình chứa đầy cà phê mới pha.","fa":"قابلمه پر از قهوه تازه است."}]},{"word":"die Kantine","en":"canteen, cafeteria","ru":"столовая","vi":"căng tin","fa":"غذاخوری","examples":[{"de":"Wir essen mittags meistens in der Kantine der Firma.","en":"We usually eat lunch in the company canteen.","ru":"Мы обычно обедаем в столовой компании.","vi":"Chúng tôi thường ăn trưa ở căng tin công ty.","fa":"ما معمولا ناهار را در غذاخوری شرکت می خوریم."},{"de":"Das Essen in der Kantine ist heute besonders gut.","en":"The food in the canteen is especially good today.","ru":"Еда в столовой сегодня особенно хороша.","vi":"Đồ ăn ở căng tin hôm nay đặc biệt ngon.","fa":"غذای غذاخوری امروز به ویژه خوب است."}]},{"word":"das Kapitel","en":"chapter","ru":"глава","vi":"chương","fa":"فصل","examples":[{"de":"Ich habe gestern das erste Kapitel des Buches gelesen.","en":"I read the first chapter of the book yesterday.","ru":"Вчера я прочитал первую главу книги.","vi":"Tôi đã đọc chương đầu tiên của cuốn sách ngày hôm qua.","fa":"من دیروز فصل اول کتاب را خواندم."},{"de":"Das letzte Kapitel war das spannendste.","en":"The last chapter was the most exciting.","ru":"Последняя глава была самой захватывающей.","vi":"Chương cuối là thú vị nhất.","fa":"فصل آخر هیجان انگیزترین بود."}]},{"word":"kaputt","en":"broken","ru":"сломанный","vi":"bị hỏng","fa":"شکسته","examples":[{"de":"Mein Handy ist kaputt, der Bildschirm funktioniert nicht mehr.","en":"My phone is broken, the screen no longer works.","ru":"Мой телефон сломан, экран больше не работает.","vi":"Điện thoại của tôi bị hỏng, màn hình không hoạt động nữa.","fa":"گوشی من خراب است، صفحه نمایش دیگر کار نمی کند."},{"de":"Die Waschmaschine ist schon wieder kaputt.","en":"The washing machine is broken again.","ru":"Стиральная машина снова сломалась.","vi":"Máy giặt lại hỏng nữa.","fa":"ماشین لباسشویی دوباره خراب است."}]},{"word":"kaputt machen","en":"to break, to ruin (something)","ru":"ломать, портить (что-либо)","vi":"phá hủy","fa":"نابود کردن","examples":[{"de":"Pass auf, du machst die Vase kaputt!","en":"Be careful, you'll break the vase!","ru":"Осторожно, ты разобьёшь вазу!","vi":"Hãy cẩn thận, bạn sẽ làm vỡ chiếc bình!","fa":"مواظب باش گلدان را می شکنی!"},{"de":"Die Kinder haben das Spielzeug kaputt gemacht.","en":"The children broke the toy.","ru":"Дети сломали игрушку.","vi":"Bọn trẻ làm vỡ đồ chơi.","fa":"بچه ها اسباب بازی را شکستند."},{"de":"Mach bitte nicht meinen Computer kaputt.","en":"Please don't break my computer.","ru":"Пожалуйста, не сломай мой компьютер.","vi":"Làm ơn đừng phá hỏng máy tính của tôi.","fa":"لطفا کامپیوتر من را خراب نکنید"}]},{"word":"kaputtgehen","en":"to break, to get broken (intransitive)","ru":"ломаться, выходить из строя (непереходный)","vi":"phá vỡ","fa":"شکستن","examples":[{"de":"Mein Handy ist gestern kaputtgegangen.","en":"My phone broke yesterday.","ru":"Мой телефон сломался вчера.","vi":"Điện thoại di động của tôi bị hỏng ngày hôm qua.","fa":"دیروز موبایلم خراب شد"},{"de":"Die Waschmaschine geht ständig kaputt.","en":"The washing machine keeps breaking.","ru":"Стиральная машина постоянно ломается.","vi":"Máy giặt liên tục hỏng.","fa":"ماشین لباسشویی مدام خراب می شود."},{"de":"Wenn du das fallen lässt, geht es kaputt.","en":"If you drop that, it'll break.","ru":"Если ты это уронишь, оно сломается.","vi":"Nếu bạn làm rơi nó, nó sẽ vỡ.","fa":"اگر آن را رها کنید، می شکند."}]},{"word":"kaputtmachen","en":"to break, to ruin (something)","ru":"ломать, портить (что-либо)","vi":"phá hủy","fa":"نابود کردن","examples":[{"de":"Du machst mit deiner Kritik alles kaputt.","en":"You ruin everything with your criticism.","ru":"Ты всё портишь своей критикой.","vi":"Bạn đang hủy hoại mọi thứ bằng những lời chỉ trích của mình.","fa":"با انتقادت همه چیز را خراب می کنی."},{"de":"Er hat aus Wut das Fenster kaputtgemacht.","en":"In a rage he smashed the window.","ru":"В ярости он разбил окно.","vi":"Anh ta đã đập vỡ cửa sổ vì tức giận.","fa":"از عصبانیت پنجره را شکست."},{"de":"Mach das Gerät nicht kaputt!","en":"Don't break the device!","ru":"Не сломай прибор!","vi":"Đừng phá vỡ thiết bị!","fa":"دستگاه را نشکنید!"}]},{"word":"der Karneval","en":"carnival","ru":"карнавал","vi":"lễ hội","fa":"کارناوال","examples":[{"de":"In Köln feiert man den Karneval sehr groß.","en":"In Cologne, carnival is celebrated on a big scale.","ru":"В Кёльне карнавал отмечают очень масштабно.","vi":"Lễ hội được tổ chức rất lớn ở Cologne.","fa":"کارناوال در کلن بسیار بزرگ جشن گرفته می شود."},{"de":"Die Kinder verkleiden sich zum Karneval als Piraten.","en":"The children dress up as pirates for carnival.","ru":"На карнавал дети наряжаются пиратами.","vi":"Những đứa trẻ hóa trang thành cướp biển trong lễ hội hóa trang.","fa":"بچه ها برای کارناوال لباس دزدان دریایی می پوشند."}]},{"word":"die Karotte","en":"carrot","ru":"морковь","vi":"củ cà rốt","fa":"هویج","examples":[{"de":"Ich schneide die Karotten für den Salat klein.","en":"I'm cutting the carrots small for the salad.","ru":"Я мелко режу морковь для салата.","vi":"Tôi cắt nhỏ cà rốt cho món salad.","fa":"من هویج را برای سالاد خرد می کنم."},{"de":"Karotten sind gut für die Augen.","en":"Carrots are good for the eyes.","ru":"Морковь полезна для глаз.","vi":"Cà rốt tốt cho mắt.","fa":"هویج برای چشم مفید است."}]},{"word":"die Karriere","en":"career","ru":"карьера","vi":"sự nghiệp","fa":"حرفه","examples":[{"de":"Sie hat eine erfolgreiche Karriere als Ärztin gemacht.","en":"She made a successful career as a doctor.","ru":"Она сделала успешную карьеру врача.","vi":"Cô đã có một sự nghiệp thành công là một bác sĩ.","fa":"او به عنوان یک پزشک حرفه ای موفق داشته است."},{"de":"Für seine Karriere ist er in eine andere Stadt gezogen.","en":"He moved to another city for his career.","ru":"Ради карьеры он переехал в другой город.","vi":"Anh ấy chuyển đến một thành phố khác để phát triển sự nghiệp của mình.","fa":"او برای کار خود به شهر دیگری نقل مکان کرد."}]},{"word":"die Karte","en":"card, map, ticket","ru":"карта, билет","vi":"cái thẻ","fa":"کارت","examples":[{"de":"Ich brauche eine Karte für den Bus.","en":"I need a ticket for the bus.","ru":"Мне нужен билет на автобус.","vi":"Tôi cần một vé đi xe buýt.","fa":"من به بلیط اتوبوس نیاز دارم."},{"de":"Kannst du mir auf der Karte zeigen, wo das Museum ist?","en":"Can you show me on the map where the museum is?","ru":"Можешь показать мне на карте, где находится музей?","vi":"Bạn có thể chỉ cho tôi trên bản đồ vị trí của bảo tàng được không?","fa":"می توانید روی نقشه به من نشان دهید که موزه کجاست؟"}]},{"word":"die Kartoffel","en":"potato","ru":"картофель","vi":"khoai tây","fa":"سیب زمینی","examples":[{"de":"Zum Mittagessen gibt es Kartoffeln mit Gemüse.","en":"For lunch there are potatoes with vegetables.","ru":"На обед картофель с овощами.","vi":"Bữa trưa có khoai tây với rau.","fa":"برای ناهار سیب زمینی با سبزیجات وجود دارد."},{"de":"Meine Oma macht die besten gebratenen Kartoffeln.","en":"My grandma makes the best fried potatoes.","ru":"Моя бабушка готовит самую вкусную жареную картошку.","vi":"Bà tôi làm món khoai tây chiên ngon nhất.","fa":"مادربزرگ من بهترین سیب زمینی سرخ شده را درست می کند."}]},{"word":"der Käse","en":"cheese","ru":"сыр","vi":"pho mát","fa":"پنیر","examples":[{"de":"Ich esse gern Brot mit Käse zum Frühstück.","en":"I like to eat bread with cheese for breakfast.","ru":"Я люблю есть на завтрак хлеб с сыром.","vi":"Tôi thích ăn bánh mì và phô mai vào bữa sáng.","fa":"من دوست دارم صبحانه نان و پنیر بخورم."},{"de":"Dieser Käse aus der Schweiz schmeckt sehr würzig.","en":"This cheese from Switzerland tastes very strong.","ru":"Этот сыр из Швейцарии очень пикантный на вкус.","vi":"Phô mai Thụy Sĩ này có vị rất cay.","fa":"طعم این پنیر سوئیسی بسیار تند است."}]},{"word":"die Kasse","en":"cash register, checkout","ru":"касса","vi":"máy tính tiền","fa":"صندوق فروش","examples":[{"de":"Bitte bezahlen Sie an der Kasse.","en":"Please pay at the checkout.","ru":"Пожалуйста, оплатите на кассе.","vi":"Vui lòng thanh toán khi thanh toán.","fa":"لطفا هنگام تسویه حساب پرداخت کنید."},{"de":"An der Kasse im Supermarkt war eine lange Schlange.","en":"There was a long line at the checkout in the supermarket.","ru":"У кассы в супермаркете была длинная очередь.","vi":"Có một hàng dài người xếp hàng trước quầy thanh toán ở siêu thị.","fa":"صف طولانی در صندوق در سوپرمارکت وجود داشت."}]},{"word":"die Kassette","en":"cassette","ru":"кассета","vi":"băng cassette","fa":"نوار کاست","examples":[{"de":"Früher haben wir Musik auf Kassetten aufgenommen.","en":"In the past we used to record music on cassettes.","ru":"Раньше мы записывали музыку на кассеты.","vi":"Chúng tôi đã từng ghi âm nhạc trên băng cassette.","fa":"ما قبلاً موسیقی را روی نوار کاست ضبط می کردیم."},{"de":"Er hat noch alte Kassetten von seiner Lieblingsband.","en":"He still has old cassettes of his favorite band.","ru":"У него всё ещё есть старые кассеты его любимой группы.","vi":"Anh ấy vẫn còn giữ những chiếc băng cassette cũ của ban nhạc yêu thích của mình.","fa":"او هنوز کاست های قدیمی از گروه مورد علاقه اش را دارد."}]},{"word":"der Kasten","en":"box, crate","ru":"ящик","vi":"cái hộp","fa":"جعبه","examples":[{"de":"In der Garage steht ein Kasten mit Werkzeug.","en":"In the garage there is a box with tools.","ru":"В гараже стоит ящик с инструментами.","vi":"Có một hộp đựng dụng cụ trong gara.","fa":"یک جعبه با ابزار در گاراژ وجود دارد."},{"de":"Er hat einen Kasten Bier für die Party gekauft.","en":"He bought a crate of beer for the party.","ru":"Он купил ящик пива для вечеринки.","vi":"Anh ấy đã mua một thùng bia cho bữa tiệc.","fa":"او یک جعبه آبجو برای مهمانی خرید."}]},{"word":"der Katalog","en":"catalog","ru":"каталог","vi":"danh mục","fa":"کاتالوگ","examples":[{"de":"Wir haben die neuen Möbel im Katalog ausgesucht.","en":"We picked out the new furniture from the catalog.","ru":"Мы выбрали новую мебель по каталогу.","vi":"Chúng tôi đã chọn đồ nội thất mới trong danh mục.","fa":"ما مبلمان جدید را در کاتالوگ انتخاب کردیم."},{"de":"Der Katalog zeigt alle Produkte mit Preisen.","en":"The catalog shows all products with prices.","ru":"В каталоге показаны все товары с ценами.","vi":"Danh mục hiển thị tất cả các sản phẩm có giá.","fa":"کاتالوگ تمام محصولات را با قیمت نشان می دهد."}]},{"word":"die Katastrophe","en":"catastrophe, disaster","ru":"катастрофа","vi":"thảm họa","fa":"فاجعه","examples":[{"de":"Das Erdbeben war eine große Katastrophe für die Region.","en":"The earthquake was a big catastrophe for the region.","ru":"Землетрясение стало большой катастрофой для региона.","vi":"Trận động đất là một thảm họa lớn đối với khu vực.","fa":"این زلزله یک فاجعه بزرگ برای منطقه بود."},{"de":"Zum Glück ist die Katastrophe ohne Verletzte verlaufen.","en":"Fortunately, the disaster happened without any injuries.","ru":"К счастью, катастрофа обошлась без пострадавших.","vi":"May mắn thay, thảm họa đã qua mà không có ai bị thương.","fa":"خوشبختانه این فاجعه بدون هیچ آسیبی سپری شد."}]},{"word":"die Kategorie","en":"category","ru":"категория","vi":"danh mục","fa":"دسته بندی","examples":[{"de":"Die Forscher teilten die Ergebnisse in drei Kategorien ein.","en":"The researchers divided the results into three categories.","ru":"Исследователи разделили результаты на три категории.","vi":"Các nhà nghiên cứu chia kết quả thành ba loại.","fa":"محققان نتایج را به سه دسته تقسیم کردند."},{"de":"Dieses Buch passt in keine einzige Kategorie.","en":"This book does not fit into any single category.","ru":"Эта книга не подходит ни под одну категорию.","vi":"Cuốn sách này không phù hợp với bất kỳ thể loại duy nhất.","fa":"این کتاب در هیچ دسته بندی واحدی قرار نمی گیرد."},{"de":"In welche Kategorie gehört dieser Film deiner Meinung nach?","en":"Which category does this film belong to, in your opinion?","ru":"К какой категории, по-твоему, относится этот фильм?","vi":"Bạn nghĩ bộ phim này thuộc thể loại nào?","fa":"به نظر شما این فیلم جزو کدام دسته است؟"}]},{"word":"die Katze im Sack kaufen","en":"to buy a pig in a poke (buy without checking)","ru":"купить кота в мешке","vi":"mua một con lợn trong một cái chọc","fa":"برای خرید یک خوک در یک پوک","examples":[{"de":"Ohne das Auto zu testen, kaufe ich doch nicht die Katze im Sack.","en":"Without testing the car, I'm not buying a pig in a poke.","ru":"Не проверив машину, я не стану покупать кота в мешке.","vi":"Nếu không chạy thử xe thì tôi sẽ không mua một con lợn chọc ghẹo.","fa":"بدون تست ماشین، من یک خوک در یک پوک نمی خرم."}]},{"word":"der Kauf","en":"purchase","ru":"покупка","vi":"việc mua hàng","fa":"خرید","examples":[{"de":"Der Kauf des Autos war eine gute Entscheidung.","en":"The purchase of the car was a good decision.","ru":"Покупка машины была хорошим решением.","vi":"Mua xe là một quyết định đúng đắn.","fa":"خرید ماشین تصمیم خوبی بود."},{"de":"Vor dem Kauf solltest du die Preise vergleichen.","en":"Before the purchase you should compare the prices.","ru":"Перед покупкой тебе стоит сравнить цены.","vi":"Trước khi mua bạn nên so sánh giá cả.","fa":"قبل از خرید باید قیمت ها را مقایسه کنید."},{"de":"Beim Kauf eines Hauses braucht man viel Geduld.","en":"When buying a house you need a lot of patience.","ru":"При покупке дома нужно много терпения.","vi":"Mua nhà đòi hỏi rất nhiều kiên nhẫn.","fa":"خرید خانه به صبر و حوصله زیادی نیاز دارد."}]},{"word":"der Käufer","en":"buyer; purchaser","ru":"покупатель","vi":"người mua","fa":"خریدار","examples":[{"de":"Der Käufer hat das Auto sofort bezahlt.","en":"The buyer paid for the car straight away.","ru":"Покупатель сразу оплатил машину.","vi":"Người mua thanh toán tiền xe ngay lập tức.","fa":"خریدار بلافاصله هزینه ماشین را پرداخت کرد."},{"de":"Für dieses Haus gibt es schon mehrere Käufer.","en":"There are already several buyers for this house.","ru":"На этот дом уже есть несколько покупателей.","vi":"Hiện đã có nhiều người mua căn nhà này.","fa":"در حال حاضر چندین خریدار برای این خانه وجود دارد."},{"de":"Der Verkäufer beriet den Käufer ausführlich.","en":"The salesman advised the buyer in detail.","ru":"Продавец подробно проконсультировал покупателя.","vi":"Người bán đã tư vấn chi tiết cho người mua.","fa":"فروشنده به خریدار مشاوره دقیق داد."}]},{"word":"die Käuferin","en":"buyer; purchaser (female)","ru":"покупательница","vi":"người mua","fa":"خریدار","examples":[{"de":"Die Käuferin verlangte einen Rabatt.","en":"The buyer asked for a discount.","ru":"Покупательница потребовала скидку.","vi":"Người mua yêu cầu giảm giá.","fa":"خریدار درخواست تخفیف کرد."},{"de":"Die Käuferin war mit der Ware sehr zufrieden.","en":"The buyer was very satisfied with the goods.","ru":"Покупательница осталась очень довольна товаром.","vi":"Người mua rất hài lòng với hàng hóa.","fa":"خریدار از کالا بسیار راضی بود."},{"de":"Eine Käuferin hat sich über das Produkt beschwert.","en":"A buyer complained about the product.","ru":"Одна покупательница пожаловалась на продукт.","vi":"Một người mua phàn nàn về sản phẩm.","fa":"یک خریدار از محصول شکایت کرد."}]},{"word":"kaum","en":"hardly","ru":"едва, почти не","vi":"khó","fa":"به سختی","examples":[{"de":"Ich habe heute kaum Zeit, ich muss viel arbeiten.","en":"I hardly have time today, I have to work a lot.","ru":"Сегодня у меня почти нет времени, мне нужно много работать.","vi":"Hôm nay tôi hầu như không có thời gian, tôi phải làm việc rất nhiều.","fa":"امروز به سختی وقت دارم، باید خیلی کار کنم."},{"de":"Es regnet so laut, dass man kaum etwas hört.","en":"It's raining so loudly that you can hardly hear anything.","ru":"Дождь идёт так громко, что почти ничего не слышно.","vi":"Trời đang mưa to đến nỗi bạn khó có thể nghe thấy gì.","fa":"آنقدر باران می بارد که به سختی می توانی چیزی بشنوی."}]},{"word":"kein-","en":"no, not any (negation article)","ru":"никакой, не (отрицательный артикль)","vi":"không-","fa":"نه-","examples":[{"de":"Ich habe heute keine Zeit für einen Kaffee.","en":"I have no time for a coffee today.","ru":"У меня сегодня нет времени на кофе.","vi":"Hôm nay tôi không có thời gian uống cà phê.","fa":"امروز وقت قهوه ندارم"},{"de":"Er hat kein Geld dabei.","en":"He has no money with him.","ru":"У него с собой нет денег.","vi":"Anh ta không mang theo tiền.","fa":"او هیچ پولی با خود ندارد."}]},{"word":"der Keller","en":"cellar, basement","ru":"подвал","vi":"hầm","fa":"زیرزمین","examples":[{"de":"Wir lagern das Gemüse im kühlen Keller.","en":"We store the vegetables in the cool cellar.","ru":"Мы храним овощи в прохладном подвале.","vi":"Chúng tôi bảo quản rau trong hầm mát.","fa":"سبزیجات را در انبار خنک نگهداری می کنیم."},{"de":"Im Keller unseres Hauses steht die Waschmaschine.","en":"The washing machine is in the basement of our house.","ru":"В подвале нашего дома стоит стиральная машина.","vi":"Máy giặt ở tầng hầm nhà chúng tôi.","fa":"ماشین لباسشویی در زیرزمین خانه ماست."}]},{"word":"der Kellner","en":"waiter","ru":"официант","vi":"người phục vụ","fa":"گارسون","examples":[{"de":"Der Kellner brachte uns die Speisekarte.","en":"The waiter brought us the menu.","ru":"Официант принёс нам меню.","vi":"Người phục vụ đưa cho chúng tôi thực đơn.","fa":"گارسون منو برای ما آورد."},{"de":"Ich habe den Kellner um die Rechnung gebeten.","en":"I asked the waiter for the bill.","ru":"Я попросил официанта принести счёт.","vi":"Tôi hỏi người phục vụ tính tiền.","fa":"از پیشخدمت صورتحساب را خواستم."}]},{"word":"die Kellnerin","en":"waitress","ru":"официантка","vi":"cô hầu bàn","fa":"پیشخدمت","examples":[{"de":"Die Kellnerin nahm unsere Bestellung auf.","en":"The waitress took our order.","ru":"Официантка приняла наш заказ.","vi":"Cô phục vụ nhận lệnh của chúng tôi.","fa":"پیشخدمت سفارش ما را گرفت."},{"de":"Sie arbeitet abends als Kellnerin im Restaurant.","en":"She works as a waitress in the restaurant in the evenings.","ru":"По вечерам она работает официанткой в ресторане.","vi":"Cô ấy làm nhân viên phục vụ ở nhà hàng vào buổi tối.","fa":"او عصرها در رستوران به عنوان پیشخدمت کار می کند."},{"de":"Die Kellnerin empfahl uns das Tagesgericht.","en":"The waitress recommended the dish of the day to us.","ru":"Официантка порекомендовала нам блюдо дня.","vi":"Người phục vụ đề nghị món đặc biệt hàng ngày cho chúng tôi.","fa":"پیشخدمت غذای ویژه روزانه را به ما توصیه کرد."}]},{"word":"kennen","en":"to know (be acquainted with)","ru":"знать (быть знакомым с кем-л./чем-л.)","vi":"biết","fa":"دانستن","examples":[{"de":"Ich kenne diese Stadt sehr gut.","en":"I know this city very well.","ru":"Я очень хорошо знаю этот город.","vi":"Tôi biết rất rõ thành phố này.","fa":"من این شهر را به خوبی می شناسم."},{"de":"Kennst du meinen Bruder?","en":"Do you know my brother?","ru":"Ты знаешь моего брата?","vi":"Bạn có biết anh trai tôi không?","fa":"آیا برادر من را می شناسید؟"}]},{"word":"die Kenntnis","en":"knowledge (of something)","ru":"знание","vi":"kiến thức","fa":"دانش","examples":[{"de":"Für diesen Job sind gute Englischkenntnisse nötig.","en":"Good knowledge of English is required for this job.","ru":"Для этой работы нужны хорошие знания английского.","vi":"Kỹ năng tiếng Anh tốt là cần thiết cho công việc này.","fa":"مهارت خوب انگلیسی برای این شغل مورد نیاز است."},{"de":"Ich habe erst gestern Kenntnis davon bekommen.","en":"I only became aware of it yesterday.","ru":"Я узнал об этом только вчера.","vi":"Tôi chỉ mới biết về nó ngày hôm qua.","fa":"من تازه دیروز متوجه شدم."}]},{"word":"die Kenntnisse","en":"knowledge; skills","ru":"знания; навыки","vi":"kiến thức","fa":"دانش","examples":[{"de":"Er hat gute Kenntnisse in Englisch.","en":"He has good knowledge of English.","ru":"У него хорошие знания английского языка.","vi":"Anh ấy có kiến thức tốt về tiếng Anh.","fa":"او دانش انگلیسی خوبی دارد."},{"de":"Für den Job braucht man EDV-Kenntnisse.","en":"For the job you need computer skills.","ru":"Для этой работы нужны знания компьютера.","vi":"Công việc đòi hỏi kỹ năng máy tính.","fa":"این شغل به مهارت های کامپیوتری نیاز دارد."}]},{"word":"das Kennwort","en":"a password (a more formal synonym of Passwort)","ru":"пароль (более формальный синоним слова Passwort)","vi":"mật khẩu","fa":"رمز عبور","examples":[{"de":"Statt Passwort sagt man manchmal auch Kennwort.","en":"Instead of 'Passwort', people sometimes also say 'Kennwort'.","ru":"Вместо «Passwort» иногда говорят «Kennwort».","vi":"Đôi khi người ta nói mật khẩu thay vì mật khẩu.","fa":"گاهی اوقات افراد به جای رمز عبور رمز عبور می گویند."},{"de":"Geben Sie bitte Ihr Kennwort ein, um fortzufahren.","en":"Please enter your password to continue.","ru":"Введите, пожалуйста, свой пароль, чтобы продолжить.","vi":"Vui lòng nhập mật khẩu của bạn để tiếp tục.","fa":"لطفا برای ادامه رمز عبور خود را وارد کنید."},{"de":"Das Kennwort für das WLAN steht auf der Rückseite des Routers.","en":"The password for the Wi-Fi is on the back of the router.","ru":"Пароль от Wi-Fi указан на обратной стороне роутера.","vi":"Mật khẩu của mạng WLAN nằm ở mặt sau của bộ định tuyến.","fa":"رمز عبور WLAN در پشت روتر قرار دارد."}]},{"word":"das Kennzeichen","en":"license plate; distinguishing mark","ru":"номерной знак; отличительный признак","vi":"biển số xe","fa":"پلاک","examples":[{"de":"Ich habe mir das Kennzeichen des Autos notiert.","en":"I noted down the car's license plate.","ru":"Я записал номерной знак машины.","vi":"Tôi đã ghi lại biển số xe.","fa":"شماره پلاک ماشین رو یادداشت کردم."},{"de":"Ehrlichkeit ist ein Kennzeichen seines Charakters.","en":"Honesty is a distinguishing feature of his character.","ru":"Честность — отличительная черта его характера.","vi":"Sự trung thực là một đặc điểm nổi bật trong tính cách của anh ấy.","fa":"صداقت از ویژگی های شخصیت اوست."}]},{"word":"die Kerze","en":"candle","ru":"свеча","vi":"ngọn nến","fa":"شمع","examples":[{"de":"Sie zündete eine Kerze auf dem Tisch an.","en":"She lit a candle on the table.","ru":"Она зажгла свечу на столе.","vi":"Cô thắp một ngọn nến trên bàn.","fa":"روی میز شمعی روشن کرد."},{"de":"Die Kerze brannte die ganze Nacht.","en":"The candle burned all night.","ru":"Свеча горела всю ночь.","vi":"Ngọn nến cháy suốt đêm.","fa":"شمع تمام شب سوخت."}]},{"word":"die Kette","en":"chain; necklace","ru":"цепь; цепочка","vi":"chuỗi","fa":"زنجیره","examples":[{"de":"Sie trägt eine goldene Kette um den Hals.","en":"She wears a gold chain around her neck.","ru":"Она носит на шее золотую цепочку.","vi":"Cô ấy đeo một sợi dây chuyền vàng quanh cổ.","fa":"زنجیر طلایی به گردنش انداخته است."},{"de":"Das Fahrrad hat eine kaputte Kette.","en":"The bicycle has a broken chain.","ru":"У велосипеда сломана цепь.","vi":"Chiếc xe đạp bị đứt xích.","fa":"دوچرخه دارای زنجیر شکسته است."}]},{"word":"das Kind","en":"child","ru":"ребёнок","vi":"đứa trẻ","fa":"کودک","examples":[{"de":"Das Kind spielt im Garten.","en":"The child is playing in the garden.","ru":"Ребёнок играет в саду.","vi":"Đứa trẻ chơi trong vườn.","fa":"کودک در باغ بازی می کند."},{"de":"Sie haben drei Kinder.","en":"They have three children.","ru":"У них трое детей.","vi":"Họ có ba đứa con.","fa":"آنها سه فرزند دارند."}]},{"word":"die Kindheit","en":"childhood","ru":"детство","vi":"tuổi thơ","fa":"دوران کودکی","examples":[{"de":"Ich habe eine glückliche Kindheit gehabt.","en":"I had a happy childhood.","ru":"У меня было счастливое детство.","vi":"Tôi đã có một tuổi thơ hạnh phúc.","fa":"کودکی شادی داشتم."},{"de":"In meiner Kindheit lebten wir auf dem Land.","en":"In my childhood we lived in the countryside.","ru":"В детстве мы жили в деревне.","vi":"Khi tôi còn nhỏ chúng tôi sống ở nông thôn.","fa":"وقتی بچه بودم در کشور زندگی می کردیم."},{"de":"Sie erinnert sich gern an ihre Kindheit.","en":"She likes to remember her childhood.","ru":"Она с удовольствием вспоминает своё детство.","vi":"Cô trìu mến nhớ lại thời thơ ấu của mình.","fa":"او با عشق از دوران کودکی خود یاد می کند."}]},{"word":"das Kino","en":"cinema","ru":"кино, кинотеатр","vi":"rạp chiếu phim","fa":"سینما","examples":[{"de":"Wir gehen heute Abend ins Kino.","en":"We're going to the cinema tonight.","ru":"Сегодня вечером мы идём в кино.","vi":"Chúng ta sẽ đi xem phim tối nay.","fa":"امشب میریم سینما"},{"de":"Der neue Film läuft schon im Kino.","en":"The new movie is already showing at the cinema.","ru":"Новый фильм уже идёт в кинотеатре.","vi":"Bộ phim mới đã được chiếu tại các rạp chiếu phim.","fa":"فیلم جدید هم اکنون در سینماها نمایش داده می شود."}]},{"word":"der Kiosk","en":"kiosk, newsstand","ru":"киоск","vi":"ki-ốt","fa":"کیوسک","examples":[{"de":"Am Kiosk kann man Zeitungen und Getränke kaufen.","en":"You can buy newspapers and drinks at the kiosk.","ru":"В киоске можно купить газеты и напитки.","vi":"Bạn có thể mua báo và đồ uống tại ki-ốt.","fa":"از کیوسک می توانید روزنامه و نوشیدنی بخرید."},{"de":"Der Kiosk an der Ecke hat bis spät geöffnet.","en":"The kiosk on the corner is open until late.","ru":"Киоск на углу открыт допоздна.","vi":"The kiosk on the corner is open until late.","fa":"کیوسک گوشه تا دیر وقت باز است."}]},{"word":"die Kirche","en":"church","ru":"церковь","vi":"nhà thờ","fa":"کلیسا","examples":[{"de":"Am Sonntag gehen sie in die Kirche.","en":"On Sunday they go to church.","ru":"В воскресенье они ходят в церковь.","vi":"Chủ nhật họ đi nhà thờ.","fa":"روز یکشنبه به کلیسا می روند."},{"de":"Die alte Kirche steht mitten in der Stadt.","en":"The old church stands in the middle of the town.","ru":"Старая церковь стоит в центре города.","vi":"Die alte Kirche steht mitten in der Stadt.","fa":"کلیسای قدیمی در وسط شهر است."}]},{"word":"die Kirche im Dorf lassen","en":"to not get carried away / keep things in proportion","ru":"не преувеличивать, не перегибать палку","vi":"không bị cuốn đi/ giữ mọi thứ ở mức cân đối","fa":"فریب نخوردن / چیزها را در تناسب نگه دارید","examples":[{"de":"Jetzt lass mal die Kirche im Dorf, so schlimm war es nicht.","en":"Now don't get carried away, it wasn't that bad.","ru":"Не преувеличивай, всё было не так уж плохо.","vi":"Giờ bỏ cái nhà thờ trong làng đi, cũng đâu có tệ đến thế.","fa":"حالا کلیسای دهکده را رها کن، آنقدرها هم بد نبود."}]},{"word":"das Kissen","en":"pillow, cushion","ru":"подушка","vi":"cái gối","fa":"بالش","examples":[{"de":"Ich schlafe gern mit einem weichen Kissen.","en":"I like sleeping with a soft pillow.","ru":"Я люблю спать на мягкой подушке.","vi":"Tôi thích ngủ với một chiếc gối mềm.","fa":"من دوست دارم با یک بالش نرم بخوابم."},{"de":"Sie legte ein Kissen auf den Stuhl.","en":"She put a cushion on the chair.","ru":"Она положила подушку на стул.","vi":"Cô đặt một chiếc gối lên ghế.","fa":"بالشی روی صندلی گذاشت."}]},{"word":"die Kiste","en":"box, crate","ru":"ящик","vi":"cái hộp","fa":"جعبه","examples":[{"de":"Er trägt eine schwere Kiste in den Keller.","en":"He carries a heavy box into the cellar.","ru":"Он несёт тяжёлый ящик в подвал.","vi":"Anh ta mang một chiếc hộp nặng xuống tầng hầm.","fa":"او یک جعبه سنگین را به زیرزمین حمل می کند."},{"de":"In der Kiste sind alte Bücher.","en":"There are old books in the box.","ru":"В ящике лежат старые книги.","vi":"Có những cuốn sách cũ trong hộp.","fa":"در جعبه کتاب های قدیمی وجود دارد."}]},{"word":"klagen","en":"to complain","ru":"жаловаться","vi":"phàn nàn","fa":"شکایت کردن","examples":[{"de":"Er klagt oft über sein Gehalt.","en":"He often complains about his salary.","ru":"Он часто жалуется на свою зарплату.","vi":"Anh ấy thường phàn nàn về mức lương của mình.","fa":"او اغلب از حقوق خود شاکی است."},{"de":"Sie klagte über Kopfschmerzen.","en":"She complained of a headache.","ru":"Она жаловалась на головную боль.","vi":"Cô phàn nàn về cơn đau đầu.","fa":"او از سردرد شکایت کرد."}]},{"word":"die Klammer","en":"bracket, parenthesis","ru":"скобка","vi":"khung","fa":"براکت","examples":[{"de":"Was in der Klammer steht, rechnet man zuerst aus.","en":"You work out what is inside the brackets first.","ru":"То, что стоит в скобках, вычисляют первым.","vi":"Những gì trong ngoặc được tính toán đầu tiên.","fa":"آنچه در پرانتز است ابتدا محاسبه می شود."},{"de":"Setze eine Klammer um die Summe.","en":"Put a bracket around the sum.","ru":"Поставь скобку вокруг суммы.","vi":"Đặt một dấu ngoặc xung quanh số tiền.","fa":"دور مجموع یک براکت قرار دهید."},{"de":"Ohne Klammer ändert sich das Ergebnis der Aufgabe.","en":"Without the brackets the result of the exercise changes.","ru":"Без скобок результат задачи меняется.","vi":"Không có dấu ngoặc, kết quả của nhiệm vụ sẽ thay đổi.","fa":"بدون براکت، نتیجه کار تغییر می کند."}]},{"word":"klappen","en":"to work out, go well","ru":"удаваться, получаться","vi":"thành công; suôn sẻ","fa":"خوب پیش رفتن؛ درست شدن","examples":[{"de":"Hoffentlich klappt alles mit dem neuen Job.","en":"Hopefully everything works out with the new job.","ru":"Надеюсь, всё получится с новой работой.","vi":"Hy vọng mọi việc sẽ suôn sẻ với công việc mới.","fa":"امیدوارم با کار جدید همه چیز درست شود."},{"de":"Es hat mit dem Termin gut geklappt.","en":"The appointment worked out well.","ru":"С назначением встречи всё удалось.","vi":"Cuộc hẹn diễn ra tốt đẹp.","fa":"قرار ملاقات به خوبی انجام شد."}]},{"word":"klar","en":"clear","ru":"ясный, понятный","vi":"rõ ràng","fa":"روشن","examples":[{"de":"Die Antwort war völlig klar.","en":"The answer was completely clear.","ru":"Ответ был совершенно ясным.","vi":"Câu trả lời đã hoàn toàn rõ ràng.","fa":"جواب کاملا واضح بود."},{"de":"Heute ist der Himmel klar und blau.","en":"Today the sky is clear and blue.","ru":"Сегодня небо ясное и голубое.","vi":"Heute ist der Himmel klar und blau.","fa":"امروز آسمان صاف و آبی است."}]},{"word":"klären","en":"to clarify, resolve","ru":"выяснять, прояснять","vi":"làm rõ","fa":"روشن کردن","examples":[{"de":"Wir müssen noch ein paar Fragen klären.","en":"We still need to clarify a few questions.","ru":"Нам нужно ещё прояснить несколько вопросов.","vi":"Chúng ta vẫn cần làm rõ một số câu hỏi.","fa":"هنوز باید چند سوال را روشن کنیم."},{"de":"Die Polizei konnte den Fall schnell klären.","en":"The police were able to solve the case quickly.","ru":"Полиция смогла быстро прояснить это дело.","vi":"The police were able to quickly clarify the case.","fa":"پلیس به سرعت توانست موضوع را روشن کند."}]},{"word":"klasse","en":"great, awesome (colloquial)","ru":"классно, отлично","vi":"lớp học","fa":"کلاس","examples":[{"de":"Das Konzert war einfach klasse!","en":"The concert was simply great!","ru":"Концерт был просто отличным!","vi":"Buổi hòa nhạc đơn giản là tuyệt vời!","fa":"کنسرت به سادگی عالی بود!"},{"de":"Ich finde deine Idee klasse.","en":"I think your idea is great.","ru":"Я считаю твою идею классной.","vi":"Tôi nghĩ ý tưởng của bạn là tuyệt vời.","fa":"به نظر من ایده شما عالی است."}]},{"word":"die Klasse","en":"class (school grade or category)","ru":"класс","vi":"lớp học","fa":"کلاس","examples":[{"de":"Meine Tochter ist in der fünften Klasse.","en":"My daughter is in the fifth grade.","ru":"Моя дочь учится в пятом классе.","vi":"Con gái tôi đang học lớp năm.","fa":"دختر من کلاس پنجم است."},{"de":"Wir fahren in der ersten Klasse.","en":"We are traveling in first class.","ru":"Мы едем в первом классе.","vi":"Chúng tôi đi du lịch ở khoang hạng nhất.","fa":"ما در کلاس اول سفر می کنیم."}]},{"word":"die Klassenarbeit","en":"class test, exam","ru":"контрольная работа","vi":"công việc của lớp","fa":"کار کلاس","examples":[{"de":"Morgen schreiben wir eine Klassenarbeit in Mathe.","en":"Tomorrow we're writing a class test in math.","ru":"Завтра мы пишем контрольную по математике.","vi":"Ngày mai chúng ta sẽ viết bài kiểm tra môn toán trên lớp.","fa":"فردا امتحان ریاضی می نویسیم."},{"de":"Die Klassenarbeit war schwerer als erwartet.","en":"The class test was harder than expected.","ru":"Контрольная оказалась сложнее, чем ожидалось.","vi":"Bài tập trên lớp khó hơn dự kiến.","fa":"کار کلاس سخت تر از حد انتظار بود."}]},{"word":"das Klavier","en":"piano","ru":"пианино","vi":"đàn piano","fa":"پیانو","examples":[{"de":"Sie spielt seit fünf Jahren Klavier.","en":"She has been playing the piano for five years.","ru":"Она играет на пианино уже пять лет.","vi":"Cô ấy đã chơi piano được 5 năm.","fa":"او پنج سال است که پیانو می نوازد."},{"de":"Im Wohnzimmer steht ein altes Klavier.","en":"There's an old piano in the living room.","ru":"В гостиной стоит старое пианино.","vi":"Có một cây đàn piano cũ trong phòng khách.","fa":"یک پیانوی قدیمی در اتاق نشیمن وجود دارد."}]},{"word":"kleben","en":"to stick, glue","ru":"клеить, приклеивать","vi":"cây gậy","fa":"چسباندن","examples":[{"de":"Er klebt das Poster an die Wand.","en":"He is sticking the poster on the wall.","ru":"Он клеит плакат на стену.","vi":"Anh ấy dán tấm áp phích lên tường.","fa":"پوستر را به دیوار می چسباند."},{"de":"Kannst du den Griff wieder ankleben?","en":"Can you glue the handle back on?","ru":"Можешь приклеить ручку обратно?","vi":"Bạn có thể dán lại tay cầm được không?","fa":"آیا می توانید دسته را دوباره بچسبانید؟"}]},{"word":"das Kleid","en":"dress","ru":"платье","vi":"chiếc váy","fa":"لباس","examples":[{"de":"Sie trägt ein rotes Kleid zur Party.","en":"She's wearing a red dress to the party.","ru":"Она наденет красное платье на вечеринку.","vi":"Cô mặc váy đỏ đi dự tiệc.","fa":"او برای مهمانی یک لباس قرمز پوشیده است."},{"de":"Das Kleid passt ihr sehr gut.","en":"The dress fits her very well.","ru":"Платье сидит на ней очень хорошо.","vi":"Chiếc váy rất hợp với cô ấy.","fa":"لباس خیلی بهش میاد"}]},{"word":"die Kleiderkammer","en":"clothing store (charity); wardrobe room","ru":"пункт сбора одежды (благотв.); костюмерная","vi":"phòng quần áo","fa":"اتاق لباس","examples":[{"de":"In der Kleiderkammer gibt es gebrauchte Kleidung für Bedürftige.","en":"In the clothing store there is used clothing for people in need.","ru":"В пункте сбора одежды есть подержанная одежда для нуждающихся.","vi":"Cửa hàng quần áo đã sử dụng quần áo cho những người có nhu cầu.","fa":"این فروشگاه لباس برای افراد نیازمند از لباس استفاده کرده است."},{"de":"Sie spendet alte Jacken an die Kleiderkammer.","en":"She donates old jackets to the clothing store.","ru":"Она жертвует старые куртки в пункт сбора одежды.","vi":"Cô tặng áo khoác cũ cho cửa hàng quần áo.","fa":"او ژاکت های قدیمی را به فروشگاه لباس اهدا می کند."},{"de":"Die Kleiderkammer wird von Freiwilligen geführt.","en":"The clothing store is run by volunteers.","ru":"Пунктом сбора одежды заведуют добровольцы.","vi":"Cửa hàng quần áo được điều hành bởi các tình nguyện viên.","fa":"فروشگاه پوشاک توسط داوطلبان اداره می شود."}]},{"word":"die Kleidung","en":"clothing, clothes","ru":"одежда","vi":"quần áo","fa":"لباس","examples":[{"de":"Im Koffer ist genug Kleidung für eine Woche.","en":"There's enough clothing in the suitcase for a week.","ru":"В чемодане достаточно одежды на неделю.","vi":"Có đủ quần áo trong vali cho một tuần.","fa":"برای یک هفته به اندازه کافی لباس داخل چمدان هست."},{"de":"Warme Kleidung ist im Winter wichtig.","en":"Warm clothing is important in winter.","ru":"Тёплая одежда важна зимой.","vi":"Quần áo ấm rất quan trọng trong mùa đông.","fa":"لباس گرم در زمستان مهم است."}]},{"word":"klein","en":"small","ru":"маленький","vi":"nhỏ bé","fa":"کوچک","examples":[{"de":"Sie wohnt in einer kleinen Wohnung.","en":"She lives in a small apartment.","ru":"Она живёт в маленькой квартире.","vi":"Cô sống trong một căn hộ nhỏ.","fa":"او در یک آپارتمان کوچک زندگی می کند."},{"de":"Das Kind ist noch sehr klein.","en":"The child is still very small.","ru":"Ребёнок ещё совсем маленький.","vi":"Đứa trẻ vẫn còn rất nhỏ.","fa":"بچه هنوز خیلی کوچک است."}]},{"word":"der Kleinwagen","en":"small car; compact car","ru":"малолитражка, малый автомобиль","vi":"chiếc xe nhỏ","fa":"ماشین کوچک","examples":[{"de":"In der Stadt ist ein Kleinwagen praktisch.","en":"In the city a small car is practical.","ru":"В городе малолитражка удобна.","vi":"Một chiếc xe nhỏ rất tiện dụng trong thành phố.","fa":"یک ماشین کوچک در شهر کاربردی است."},{"de":"Ein Kleinwagen verbraucht wenig Benzin.","en":"A small car uses little petrol.","ru":"Малолитражка расходует мало бензина.","vi":"Một chiếc xe nhỏ sử dụng ít xăng.","fa":"یک ماشین کوچک بنزین کمی مصرف می کند."},{"de":"Sie hat sich einen roten Kleinwagen gekauft.","en":"She bought herself a red small car.","ru":"Она купила себе красную малолитражку.","vi":"Cô ấy mua một chiếc ô tô nhỏ màu đỏ.","fa":"او یک ماشین کوچک قرمز خرید."}]},{"word":"klettern","en":"to climb","ru":"лазить, взбираться","vi":"leo lên","fa":"صعود","examples":[{"de":"Die Kinder klettern gern auf Bäume.","en":"The children like climbing trees.","ru":"Дети любят лазить по деревьям.","vi":"Trẻ em thích trèo cây.","fa":"بچه ها دوست دارند از درخت بالا بروند."},{"de":"Wir sind letztes Jahr in den Alpen geklettert.","en":"We went climbing in the Alps last year.","ru":"В прошлом году мы лазили в Альпах.","vi":"Chúng tôi đã leo lên dãy Alps vào năm ngoái.","fa":"ما سال گذشته در کوه های آلپ صعود کردیم."}]},{"word":"der Klick","en":"click","ru":"клик, щелчок (мышью)","vi":"cú nhấp chuột","fa":"کلیک","examples":[{"de":"Mit einem Klick öffnest du das Programm.","en":"With one click you open the programme.","ru":"Одним кликом ты открываешь программу.","vi":"Với một cú nhấp chuột, bạn mở chương trình.","fa":"با یک کلیک برنامه را باز می کنید."},{"de":"Das Video hat schon tausend Klicks.","en":"The video already has a thousand clicks.","ru":"У видео уже тысяча кликов.","vi":"Video đã có một nghìn lượt nhấp chuột.","fa":"ویدیو در حال حاضر هزار کلیک دارد."},{"de":"Ein falscher Klick und die Datei ist weg.","en":"One wrong click and the file is gone.","ru":"Один неверный клик — и файла нет.","vi":"Một cú nhấp chuột sai và tập tin sẽ biến mất.","fa":"یک کلیک اشتباه و فایل از بین می رود."}]},{"word":"klicken","en":"to click","ru":"щёлкать (мышью), нажимать","vi":"bấm vào","fa":"کلیک کنید","examples":[{"de":"Klicken Sie hier, um fortzufahren.","en":"Click here to continue.","ru":"Нажмите здесь, чтобы продолжить.","vi":"Nhấn vào đây để tiếp tục.","fa":"برای ادامه اینجا را کلیک کنید."},{"de":"Er klickte versehentlich auf den falschen Link.","en":"He accidentally clicked the wrong link.","ru":"Он случайно нажал не на ту ссылку.","vi":"Anh vô tình bấm nhầm vào link.","fa":"او به طور تصادفی روی لینک اشتباه کلیک کرد."}]},{"word":"das Klima","en":"climate","ru":"климат","vi":"khí hậu","fa":"آب و هوا","examples":[{"de":"In Spanien ist das Klima wärmer als in Deutschland.","en":"The climate in Spain is warmer than in Germany.","ru":"В Испании климат теплее, чем в Германии.","vi":"Khí hậu ở Tây Ban Nha ấm hơn ở Đức.","fa":"آب و هوای اسپانیا گرمتر از آلمان است."},{"de":"Der Klimawandel verändert das Klima weltweit.","en":"Climate change is altering the climate worldwide.","ru":"Изменение климата меняет климат во всём мире.","vi":"Biến đổi khí hậu đang làm thay đổi khí hậu trên toàn thế giới.","fa":"تغییرات آب و هوایی در حال تغییر اقلیم در سراسر جهان است."}]},{"word":"die Klimaanlage","en":"air conditioning, air-conditioning unit","ru":"кондиционер (климатическая установка)","vi":"điều hòa không khí","fa":"تهویه مطبوع","examples":[{"de":"Im Sommer läuft die Klimaanlage im Büro den ganzen Tag.","en":"In summer the air conditioning runs in the office all day.","ru":"Летом кондиционер в офисе работает весь день.","vi":"Mùa hè, máy lạnh trong văn phòng chạy cả ngày.","fa":"در تابستان، تهویه مطبوع در دفتر کار تمام روز است."},{"de":"Eine Klimaanlage verbraucht viel Strom und ist nicht immer umweltfreundlich.","en":"An air-conditioning unit uses a lot of electricity and is not always environmentally friendly.","ru":"Кондиционер потребляет много электричества и не всегда экологичен.","vi":"Điều hòa sử dụng nhiều điện và không phải lúc nào cũng thân thiện với môi trường.","fa":"تهویه مطبوع برق زیادی مصرف می کند و همیشه دوستدار محیط زیست نیست."},{"de":"Weil es draußen so heiß war, schalteten wir die Klimaanlage ein.","en":"Because it was so hot outside, we switched on the air conditioning.","ru":"Поскольку на улице было очень жарко, мы включили кондиционер.","vi":"Vì bên ngoài rất nóng nên chúng tôi bật điều hòa.","fa":"چون بیرون خیلی گرم بود تهویه هوا را روشن کردیم."}]},{"word":"die Klimaerwärmung","en":"global warming, climate warming","ru":"потепление климата, глобальное потепление","vi":"sự nóng lên toàn cầu","fa":"گرم شدن کره زمین","examples":[{"de":"Die Klimaerwärmung lässt die Gletscher schmelzen.","en":"Climate warming is melting the glaciers.","ru":"Потепление климата заставляет таять ледники.","vi":"Sự nóng lên toàn cầu đang khiến các sông băng tan chảy.","fa":"گرم شدن کره زمین باعث آب شدن یخچال های طبیعی می شود."},{"de":"Wissenschaftler beobachten die Klimaerwärmung seit Jahrzehnten.","en":"Scientists have been observing climate warming for decades.","ru":"Учёные наблюдают потепление климата десятилетиями.","vi":"Các nhà khoa học đã quan sát sự nóng lên toàn cầu trong nhiều thập kỷ.","fa":"دانشمندان چندین دهه است که گرمایش زمین را مشاهده می کنند."},{"de":"Die Klimaerwärmung bedroht viele Tierarten.","en":"Climate warming threatens many animal species.","ru":"Потепление климата угрожает многим видам животных.","vi":"Sự nóng lên toàn cầu đe dọa nhiều loài động vật.","fa":"گرمایش جهانی بسیاری از گونه های جانوری را تهدید می کند."}]},{"word":"die Klimaerwärmung bremsen","en":"to slow down global warming","ru":"замедлять глобальное потепление","vi":"làm chậm sự nóng lên toàn cầu","fa":"کاهش سرعت گرمایش جهانی","examples":[{"de":"Wir müssen die Klimaerwärmung dringend bremsen.","en":"We urgently need to slow down global warming.","ru":"Нам срочно нужно замедлить глобальное потепление.","vi":"Chúng ta cần khẩn trương làm chậm sự nóng lên toàn cầu.","fa":"ما نیاز فوری به کاهش گرمایش جهانی داریم."},{"de":"Erneuerbare Energien können die Klimaerwärmung bremsen.","en":"Renewable energies can slow down global warming.","ru":"Возобновляемые источники энергии могут замедлить глобальное потепление.","vi":"Năng lượng tái tạo có thể làm chậm sự nóng lên toàn cầu.","fa":"انرژی های تجدیدپذیر می توانند گرمایش جهانی را کاهش دهند."},{"de":"Jeder kann etwas tun, um die Klimaerwärmung zu bremsen.","en":"Everyone can do something to slow down global warming.","ru":"Каждый может что-то сделать, чтобы замедлить глобальное потепление.","vi":"Mọi người đều có thể làm điều gì đó để làm chậm sự nóng lên toàn cầu.","fa":"همه می توانند کاری انجام دهند تا گرمایش جهانی را کاهش دهد."}]},{"word":"klimafreundlich","en":"climate-friendly","ru":"щадящий для климата, экологичный для климата","vi":"thân thiện với khí hậu","fa":"سازگار با آب و هوا","examples":[{"de":"Mit dem Fahrrad zu fahren ist besonders klimafreundlich.","en":"Travelling by bicycle is especially climate-friendly.","ru":"Ездить на велосипеде особенно щадяще для климата.","vi":"Đi xe đạp đặc biệt thân thiện với khí hậu.","fa":"دوچرخه سواری به ویژه سازگار با آب و هوا است."},{"de":"Die Firma wirbt mit einer klimafreundlichen Produktion.","en":"The company advertises with climate-friendly production.","ru":"Фирма рекламирует климатически щадящее производство.","vi":"Công ty quảng cáo sản xuất thân thiện với khí hậu.","fa":"این شرکت محصولات سازگار با آب و هوا را تبلیغ می کند."},{"de":"Klimafreundliche Häuser brauchen sehr wenig Energie.","en":"Climate-friendly houses need very little energy.","ru":"Климатически щадящим домам нужно очень мало энергии.","vi":"Những ngôi nhà thân thiện với khí hậu cần rất ít năng lượng.","fa":"خانه های سازگار با آب و هوا به انرژی بسیار کمی نیاز دارند."}]},{"word":"die Klimakonferenz","en":"climate conference","ru":"климатическая конференция","vi":"hội nghị khí hậu","fa":"کنفرانس آب و هوا","examples":[{"de":"Auf der Klimakonferenz wurde über neue Ziele gesprochen.","en":"New targets were discussed at the climate conference.","ru":"На климатической конференции говорили о новых целях.","vi":"Các mục tiêu mới đã được thảo luận tại hội nghị về khí hậu.","fa":"اهداف جدید در کنفرانس آب و هوا مورد بحث قرار گرفت."},{"de":"Die Klimakonferenz findet dieses Jahr in Brasilien statt.","en":"The climate conference is taking place in Brazil this year.","ru":"В этом году климатическая конференция проходит в Бразилии.","vi":"Hội nghị về khí hậu sẽ diễn ra ở Brazil năm nay.","fa":"کنفرانس آب و هوا امسال در برزیل برگزار می شود."},{"de":"Viele Länder haben auf der Klimakonferenz Versprechen gegeben.","en":"Many countries made promises at the climate conference.","ru":"Многие страны дали обещания на климатической конференции.","vi":"Nhiều nước đưa ra lời hứa tại hội nghị về khí hậu.","fa":"بسیاری از کشورها در کنفرانس آب و هوا وعده هایی دادند."}]},{"word":"klimaneutral","en":"climate-neutral, carbon-neutral","ru":"климатически нейтральный, углеродно-нейтральный","vi":"khí hậu trung tính","fa":"آب و هوای خنثی","examples":[{"de":"Die Firma will bis 2035 klimaneutral werden.","en":"The company wants to become climate-neutral by 2035.","ru":"Фирма хочет стать климатически нейтральной к 2035 году.","vi":"Công ty muốn trở thành trung hòa khí hậu vào năm 2035.","fa":"این شرکت می خواهد تا سال 2035 آب و هوا خنثی شود."},{"de":"Dieses Hotel wirbt damit, klimaneutral zu sein.","en":"This hotel advertises that it is climate-neutral.","ru":"Этот отель рекламирует себя как климатически нейтральный.","vi":"Khách sạn này tự quảng cáo là trung hòa về khí hậu.","fa":"این هتل خود را به عنوان یک هتل خنثی از آب و هوا تبلیغ می کند."},{"de":"Ein klimaneutraler Versand belastet die Umwelt weniger.","en":"Climate-neutral shipping burdens the environment less.","ru":"Климатически нейтральная доставка меньше нагружает окружающую среду.","vi":"Vận chuyển trung hòa khí hậu gây ít căng thẳng hơn cho môi trường.","fa":"حمل و نقل بدون آب و هوا فشار کمتری به محیط زیست وارد می کند."}]},{"word":"der Klimaschutz","en":"climate protection","ru":"защита климата","vi":"bảo vệ khí hậu","fa":"climate protection","examples":[{"de":"Beim Klimaschutz zählt jede eingesparte Tonne CO2.","en":"In climate protection every tonne of CO2 saved counts.","ru":"В защите климата важна каждая сэкономленная тонна CO2.","vi":"Khi nói đến bảo vệ khí hậu, mỗi tấn CO2 tiết kiệm được đều có giá trị.","fa":"وقتی صحبت از حفاظت از آب و هوا می شود، هر تن CO2 ذخیره شده اهمیت دارد."},{"de":"Viele junge Leute engagieren sich für den Klimaschutz.","en":"Many young people are committed to climate protection.","ru":"Многие молодые люди активно участвуют в защите климата.","vi":"Nhiều người trẻ cam kết bảo vệ khí hậu.","fa":"بسیاری از جوانان متعهد به حفاظت از آب و هوا هستند."},{"de":"Die Regierung hat neue Gesetze zum Klimaschutz beschlossen.","en":"The government has passed new laws on climate protection.","ru":"Правительство приняло новые законы о защите климата.","vi":"Chính phủ đã thông qua luật bảo vệ khí hậu mới.","fa":"دولت قوانین جدید حفاظت از آب و هوا را تصویب کرده است."}]},{"word":"der Klimaschützer","en":"climate activist, climate protector","ru":"защитник климата, климатический активист","vi":"người bảo vệ khí hậu","fa":"محافظ آب و هوا","examples":[{"de":"Die jungen Klimaschützer demonstrieren jeden Freitag.","en":"The young climate activists demonstrate every Friday.","ru":"Молодые защитники климата выходят на демонстрации каждую пятницу.","vi":"Các nhà hoạt động khí hậu trẻ biểu tình vào thứ Sáu hàng tuần.","fa":"فعالان جوان اقلیم هر جمعه تظاهرات می کنند."},{"de":"Als Klimaschützer fährt er nie mit dem Flugzeug.","en":"As a climate activist, he never travels by plane.","ru":"Как защитник климата, он никогда не летает на самолёте.","vi":"Là một nhà hoạt động vì khí hậu, anh ấy không bao giờ di chuyển bằng máy bay.","fa":"او به عنوان یک فعال اقلیم هرگز با هواپیما سفر نمی کند."},{"de":"Viele Klimaschützer fordern strengere Gesetze.","en":"Many climate activists demand stricter laws.","ru":"Многие защитники климата требуют более строгих законов.","vi":"Nhiều nhà hoạt động khí hậu đang kêu gọi luật pháp chặt chẽ hơn.","fa":"بسیاری از فعالان آب و هوا خواستار قوانین سختگیرانه تر هستند."}]},{"word":"der Klimawandel","en":"climate change","ru":"изменение климата","vi":"biến đổi khí hậu","fa":"تغییرات آب و هوایی","examples":[{"de":"Der Klimawandel bedroht viele Tierarten.","en":"Climate change threatens many animal species.","ru":"Изменение климата угрожает многим видам животных.","vi":"Biến đổi khí hậu đe dọa nhiều loài động vật.","fa":"تغییرات آب و هوایی بسیاری از گونه های جانوری را تهدید می کند."},{"de":"Wissenschaftler warnen seit Jahren vor dem Klimawandel.","en":"Scientists have been warning about climate change for years.","ru":"Учёные уже много лет предупреждают об изменении климата.","vi":"Các nhà khoa học đã cảnh báo về biến đổi khí hậu trong nhiều năm.","fa":"دانشمندان سالهاست که درباره تغییرات آب و هوایی هشدار می دهند."}]},{"word":"die Klingel","en":"doorbell, bell","ru":"дверной звонок; звонок","vi":"cái chuông","fa":"زنگ","examples":[{"de":"Hast du nicht die Klingel gehört? Es war jemand an der Tür.","en":"Didn't you hear the doorbell? Someone was at the door.","ru":"Ты не слышал звонок? Кто-то был у двери.","vi":"Bạn không nghe thấy tiếng chuông à? Có ai đó ở cửa.","fa":"صدای زنگ را نشنیدی؟ یک نفر دم در بود."},{"de":"Unsere Klingel ist seit gestern kaputt.","en":"Our doorbell has been broken since yesterday.","ru":"Наш звонок сломан со вчерашнего дня.","vi":"Chuông của chúng tôi đã bị hỏng từ hôm qua.","fa":"زنگ ما از دیروز شکسته است."},{"de":"Drück bitte auf die Klingel mit unserem Namen.","en":"Please ring the bell with our name on it.","ru":"Нажми, пожалуйста, на звонок с нашей фамилией.","vi":"Hãy nhấn chuông có tên chúng tôi trên đó.","fa":"لطفا زنگی که نام ما روی آن است را فشار دهید."}]},{"word":"klingeln","en":"to ring (a bell)","ru":"звонить (в звонок)","vi":"chiếc nhẫn","fa":"حلقه","examples":[{"de":"Es hat an der Tür geklingelt.","en":"The doorbell rang.","ru":"В дверь позвонили.","vi":"Chuông cửa reo.","fa":"زنگ در به صدا درآمد."},{"de":"Bitte klingeln Sie, wenn Sie ankommen.","en":"Please ring the bell when you arrive.","ru":"Пожалуйста, позвоните в звонок, когда придёте.","vi":"Vui lòng bấm chuông khi bạn đến.","fa":"لطفا وقتی رسیدید زنگ را بزنید."}]},{"word":"klingen","en":"to sound","ru":"звучать","vi":"âm thanh","fa":"صدا","examples":[{"de":"Das klingt wie eine gute Idee.","en":"That sounds like a good idea.","ru":"Это звучит как хорошая идея.","vi":"Nghe có vẻ là một ý tưởng hay.","fa":"به نظر می رسد ایده خوبی است."},{"de":"Ihre Stimme klingt heute müde.","en":"Her voice sounds tired today.","ru":"Её голос сегодня звучит устало.","vi":"Giọng nói của bạn hôm nay có vẻ mệt mỏi.","fa":"امروز صدایت خسته به نظر می رسد."}]},{"word":"Das klingt gut","en":"That sounds good (positive reaction)","ru":"Звучит хорошо (положительная реакция)","vi":"Điều đó nghe có vẻ tốt","fa":"به نظر خوب می رسد","examples":[{"de":"Das klingt gut, ich bin dabei.","en":"That sounds good, I'm in.","ru":"Звучит хорошо, я участвую.","vi":"Nghe có vẻ hay đấy, tôi ở đó.","fa":"به نظر خوب می رسد، من آنجا هستم."}]},{"word":"die Klinik","en":"clinic","ru":"клиника","vi":"phòng khám","fa":"کلینیک","examples":[{"de":"Er wurde sofort in die Klinik gebracht.","en":"He was immediately taken to the clinic.","ru":"Его немедленно доставили в клинику.","vi":"Anh ngay lập tức được đưa đến phòng khám.","fa":"او بلافاصله به درمانگاه منتقل شد."},{"de":"Die Klinik ist auf Herzkrankheiten spezialisiert.","en":"The clinic specializes in heart diseases.","ru":"Клиника специализируется на сердечных заболеваниях.","vi":"Phòng khám chuyên về bệnh tim mạch.","fa":"این کلینیک در زمینه بیماری های قلبی تخصص دارد."}]},{"word":"klopfen","en":"to knock","ru":"стучать","vi":"gõ cửa","fa":"در زدن","examples":[{"de":"Jemand klopft an der Tür.","en":"Someone is knocking on the door.","ru":"Кто-то стучит в дверь.","vi":"Có người gõ cửa.","fa":"یک نفر در را می زند."},{"de":"Sie klopfte höflich, bevor sie eintrat.","en":"She knocked politely before entering.","ru":"Она вежливо постучала, прежде чем войти.","vi":"Cô lịch sự gõ cửa trước khi bước vào.","fa":"قبل از ورود مودبانه در زد."}]},{"word":"der Kloß","en":"dumpling","ru":"клёцка","vi":"bánh bao","fa":"پیراشکی","examples":[{"de":"Zum Braten gibt es Klöße.","en":"Dumplings are served with the roast.","ru":"К жаркому подают клёцки.","vi":"Có bánh bao để chiên.","fa":"کوفته هایی برای سرخ کردن وجود دارد."},{"de":"Meine Oma macht die besten Klöße.","en":"My grandma makes the best dumplings.","ru":"Моя бабушка делает лучшие клёцки.","vi":"Bà tôi làm bánh bao ngon nhất.","fa":"مادربزرگ من بهترین کوفته ها را درست می کند."}]},{"word":"klug","en":"clever, smart","ru":"умный","vi":"thông minh","fa":"باهوش","examples":[{"de":"Sie ist eine sehr kluge Studentin.","en":"She is a very clever student.","ru":"Она очень умная студентка.","vi":"Cô ấy là một học sinh rất thông minh.","fa":"او دانش آموز بسیار باهوشی است."},{"de":"Das war eine kluge Entscheidung.","en":"That was a smart decision.","ru":"Это было умное решение.","vi":"Đó là một quyết định sáng suốt.","fa":"این تصمیم عاقلانه ای بود."}]},{"word":"knapp","en":"scarce, tight; barely, just","ru":"ограниченный, дефицитный; едва, чуть","vi":"khan hiếm","fa":"کمیاب","examples":[{"de":"Unsere Zeit ist knapp.","en":"Our time is short.","ru":"Нашего времени в обрез.","vi":"Thời gian của chúng ta rất ngắn.","fa":"زمان ما کوتاه است."},{"de":"Er hat den Zug nur knapp geschafft.","en":"He barely made the train.","ru":"Он еле успел на поезд.","vi":"Anh ấy hầu như không thực hiện được hành động.","fa":"او به سختی حرکت را انجام داد."}]},{"word":"die Kneipe","en":"pub, bar","ru":"пивная, паб","vi":"quán rượu","fa":"میخانه","examples":[{"de":"Wir treffen uns abends in der Kneipe.","en":"We meet up at the pub in the evening.","ru":"Вечером мы встречаемся в пивной.","vi":"Chúng tôi gặp nhau ở quán rượu vào buổi tối.","fa":"عصر در میخانه همدیگر را می بینیم."},{"de":"In dieser Kneipe gibt es gutes Bier.","en":"This pub has good beer.","ru":"В этом пабе хорошее пиво.","vi":"Có bia ngon ở quán rượu này.","fa":"آبجو خوبی در این میخانه وجود دارد."}]},{"word":"das Knie","en":"knee","ru":"колено","vi":"đầu gối","fa":"زانو","examples":[{"de":"Er hat sich beim Fußball das Knie verletzt.","en":"He injured his knee playing football.","ru":"Он повредил колено, играя в футбол.","vi":"Anh ấy bị thương ở đầu gối khi chơi bóng đá.","fa":"او در بازی فوتبال زانویش آسیب دید."},{"de":"Die Kinder saßen auf dem Knie des Opas.","en":"The children sat on grandpa's knee.","ru":"Дети сидели на коленях у дедушки.","vi":"Bọn trẻ ngồi trên đầu gối của ông nội.","fa":"بچه ها روی زانوی پدربزرگ نشستند."}]},{"word":"der Knochen","en":"bone","ru":"кость","vi":"xương","fa":"استخوان","examples":[{"de":"Der Hund kaut gern an einem Knochen.","en":"The dog likes to chew on a bone.","ru":"Собака любит грызть кость.","vi":"Con chó thích nhai xương.","fa":"سگ دوست دارد استخوان بجود."},{"de":"Bei dem Sturz hat er sich einen Knochen gebrochen.","en":"He broke a bone in the fall.","ru":"При падении он сломал кость.","vi":"Anh ấy bị gãy xương vào mùa thu.","fa":"او در پاییز یک استخوان شکست."}]},{"word":"der Knödel","en":"dumpling","ru":"кнедлик","vi":"bánh bao","fa":"پیراشکی","examples":[{"de":"In Bayern isst man oft Knödel zum Fleisch.","en":"In Bavaria, dumplings are often eaten with meat.","ru":"В Баварии кнедлики часто едят с мясом.","vi":"Ở Bavaria người ta thường ăn bánh bao với thịt.","fa":"در باواریا مردم اغلب کوفته ها را با گوشت می خورند."},{"de":"Sie kocht Knödel aus Kartoffeln.","en":"She cooks dumplings made of potatoes.","ru":"Она варит кнедлики из картофеля.","vi":"Cô ấy nấu bánh bao từ khoai tây.","fa":"او از سیب زمینی کوفته می پزد."}]},{"word":"der Knopf","en":"button","ru":"пуговица; кнопка","vi":"cái nút","fa":"دکمه","examples":[{"de":"An der Jacke fehlt ein Knopf.","en":"A button is missing from the jacket.","ru":"На куртке не хватает пуговицы.","vi":"Một chiếc nút bị thiếu trên áo khoác.","fa":"یک دکمه از کت گم شده است."},{"de":"Drück auf den roten Knopf, um die Maschine zu starten.","en":"Press the red button to start the machine.","ru":"Нажми красную кнопку, чтобы запустить машину.","vi":"Nhấn nút màu đỏ để khởi động máy.","fa":"دکمه قرمز را فشار دهید تا دستگاه روشن شود."}]},{"word":"der Ko","en":"KO; knockout","ru":"нокаут; (разг.) без сил, вымотанный","vi":"loại trực tiếp","fa":"ناک اوت","examples":[{"de":"Der Boxer gewann den Kampf durch Ko.","en":"The boxer won the fight by KO.","ru":"Боксёр выиграл бой нокаутом.","vi":"Võ sĩ đã thắng trận đấu bằng loại trực tiếp.","fa":"بوکسور در این مبارزه با ناک اوت پیروز شد."},{"de":"Nach dem langen Tag war ich völlig Ko.","en":"After the long day I was completely knackered.","ru":"После долгого дня я был совершенно без сил.","vi":"Sau một ngày dài tôi hoàn toàn kiệt sức.","fa":"بعد از یک روز طولانی کاملاً ناک اوت شدم."},{"de":"Ein harter Schlag, und der Gegner ging Ko.","en":"One hard blow, and the opponent went down for the count.","ru":"Один сильный удар — и соперник ушёл в нокаут.","vi":"Một đòn mạnh và đối thủ bị hạ gục.","fa":"ضربه سختی زد و حریف ناک اوت شد."}]},{"word":"die Koalition","en":"coalition","ru":"коалиция","vi":"liên minh","fa":"ائتلاف","examples":[{"de":"Zwei Parteien bildeten eine Koalition.","en":"Two parties formed a coalition.","ru":"Две партии образовали коалицию.","vi":"Hai bên thành lập liên minh.","fa":"دو حزب ائتلاف تشکیل دادند."},{"de":"Die Koalition einigte sich auf einen gemeinsamen Plan.","en":"The coalition agreed on a joint plan.","ru":"Коалиция договорилась об общем плане.","vi":"Liên minh đã thống nhất một kế hoạch chung.","fa":"ائتلاف بر سر یک طرح مشترک به توافق رسید."},{"de":"Die Koalition zerbrach nach nur einem Jahr.","en":"The coalition broke apart after only one year.","ru":"Коалиция распалась всего через год.","vi":"Liên minh sụp đổ chỉ sau một năm.","fa":"این ائتلاف تنها پس از یک سال فروپاشید."}]},{"word":"der Koch","en":"cook; chef","ru":"повар, шеф-повар","vi":"đầu bếp","fa":"آشپز","examples":[{"de":"Der Koch bereitet das Essen in der Küche zu.","en":"The cook prepares the food in the kitchen.","ru":"Повар готовит еду на кухне.","vi":"Đầu bếp chuẩn bị thức ăn trong bếp.","fa":"آشپز غذا را در آشپزخانه آماده می کند."},{"de":"Mein Vater ist ein ausgezeichneter Koch.","en":"My father is an excellent cook.","ru":"Мой отец — превосходный повар.","vi":"Bố tôi là một đầu bếp giỏi.","fa":"پدر من آشپز فوق العاده ای است."},{"de":"Der Koch des Restaurants ist sehr berühmt.","en":"The restaurant's chef is very famous.","ru":"Шеф-повар ресторана очень знаменит.","vi":"Đầu bếp của nhà hàng rất nổi tiếng.","fa":"سرآشپز رستوران بسیار معروف است."}]},{"word":"kochen","en":"to cook","ru":"готовить (еду)","vi":"nấu ăn","fa":"پختن","examples":[{"de":"Meine Mutter kocht jeden Abend das Essen.","en":"My mother cooks dinner every evening.","ru":"Моя мама готовит ужин каждый вечер.","vi":"Mẹ tôi nấu bữa tối mỗi tối.","fa":"مادرم هر روز عصر شام درست می کند."},{"de":"Kannst du gut kochen?","en":"Can you cook well?","ru":"Ты хорошо готовишь?","vi":"Bạn có giỏi nấu ăn không?","fa":"آیا در آشپزی خوب هستید؟"}]},{"word":"die Köchin","en":"cook; chef (female)","ru":"повариха (ж.)","vi":"đầu bếp","fa":"آشپز","examples":[{"de":"Die Köchin bereitet jeden Tag frische Suppe zu.","en":"The cook prepares fresh soup every day.","ru":"Повариха каждый день готовит свежий суп.","vi":"Người đầu bếp chuẩn bị món súp tươi mỗi ngày.","fa":"آشپز هر روز سوپ تازه درست می کند."},{"de":"Unsere Köchin arbeitet in einem großen Restaurant.","en":"Our cook works in a large restaurant.","ru":"Наша повариха работает в большом ресторане.","vi":"Đầu bếp của chúng tôi làm việc trong một nhà hàng lớn.","fa":"آشپز ما در یک رستوران بزرگ کار می کند."},{"de":"Die Köchin schmeckte die Soße mit Salz ab.","en":"The cook seasoned the sauce with salt.","ru":"Повариха посолила соус по вкусу.","vi":"Người đầu bếp nếm thử nước sốt với muối.","fa":"آشپز سس را با نمک میل کرد."}]},{"word":"koffeinfrei","en":"caffeine-free, decaffeinated","ru":"без кофеина, декофеинизированный","vi":"không chứa caffeine","fa":"بدون کافئین","examples":[{"de":"Am Abend trinke ich nur koffeinfreien Kaffee.","en":"In the evening I only drink decaffeinated coffee.","ru":"Вечером я пью только кофе без кофеина.","vi":"Vào buổi tối tôi chỉ uống cà phê đã khử caffein.","fa":"عصرها فقط قهوه بدون کافئین می نوشم."},{"de":"Diese Cola ist zuckerfrei und koffeinfrei.","en":"This cola is sugar-free and caffeine-free.","ru":"Эта кола без сахара и без кофеина.","vi":"Loại cola này không chứa đường và không chứa caffeine.","fa":"این کولا بدون قند و کافئین است."},{"de":"Schwangere greifen oft zu koffeinfreien Getränken.","en":"Pregnant women often reach for caffeine-free drinks.","ru":"Беременные часто выбирают напитки без кофеина.","vi":"Bà bầu thường chọn đồ uống không chứa caffeine.","fa":"زنان باردار اغلب نوشیدنی های بدون کافئین را انتخاب می کنند."}]},{"word":"der Koffer","en":"suitcase","ru":"чемодан","vi":"chiếc vali","fa":"چمدان","examples":[{"de":"Ich packe meinen Koffer für die Reise.","en":"I'm packing my suitcase for the trip.","ru":"Я собираю чемодан для поездки.","vi":"Tôi đang đóng gói hành lý cho chuyến đi.","fa":"دارم چمدانم را برای سفر می بندم."},{"de":"Der Koffer war zu schwer für das Flugzeug.","en":"The suitcase was too heavy for the plane.","ru":"Чемодан оказался слишком тяжёлым для самолёта.","vi":"Chiếc vali quá nặng so với máy bay.","fa":"چمدان برای هواپیما خیلی سنگین بود."}]},{"word":"die Kohle","en":"coal","ru":"уголь","vi":"than","fa":"زغال سنگ","examples":[{"de":"Viele Kraftwerke verbrennen noch immer Kohle.","en":"Many power stations still burn coal.","ru":"Многие электростанции всё ещё сжигают уголь.","vi":"Nhiều nhà máy điện vẫn đốt than.","fa":"بسیاری از نیروگاه ها هنوز زغال سنگ می سوزانند."},{"de":"Die Verbrennung von Kohle ist besonders schädlich für das Klima.","en":"Burning coal is especially harmful to the climate.","ru":"Сжигание угля особенно вредно для климата.","vi":"Đốt than đặc biệt có hại cho khí hậu.","fa":"سوزاندن زغال سنگ به ویژه برای آب و هوا مضر است."},{"de":"Deutschland will langsam aus der Kohle aussteigen.","en":"Germany wants to phase out coal slowly.","ru":"Германия хочет постепенно отказаться от угля.","vi":"Đức muốn từ từ loại bỏ than.","fa":"آلمان می خواهد به تدریج زغال سنگ را حذف کند."}]},{"word":"die Kohlensäure","en":"carbon dioxide (in drinks), fizz","ru":"углекислый газ (в напитках), газированность","vi":"axit cacbonic","fa":"اسید کربنیک","examples":[{"de":"Ich mag Wasser ohne Kohlensäure.","en":"I like water without fizz.","ru":"Я люблю воду без газа.","vi":"Tôi thích nước không có ga.","fa":"من آب بدون گاز را دوست دارم."},{"de":"Die Kohlensäure macht das Getränk spritzig.","en":"The carbonation makes the drink fizzy.","ru":"Углекислый газ делает напиток газированным.","vi":"Carbon dioxide làm cho đồ uống có ga.","fa":"دی اکسید کربن نوشیدنی را درخشان می کند."},{"de":"Nach ein paar Tagen verliert die Brause ihre Kohlensäure.","en":"After a few days the fizzy drink loses its carbonation.","ru":"Через несколько дней шипучка теряет свою газированность.","vi":"Sau một vài ngày, vòi hoa sen sẽ mất đi lượng carbon dioxide.","fa":"بعد از چند روز دوش دی اکسید کربن خود را از دست می دهد."}]},{"word":"der Kollege","en":"colleague","ru":"коллега","vi":"đồng nghiệp","fa":"همکار","examples":[{"de":"Mein Kollege hilft mir bei der Arbeit.","en":"My colleague helps me with work.","ru":"Мой коллега помогает мне на работе.","vi":"Đồng nghiệp của tôi giúp đỡ tôi trong công việc.","fa":"همکارم در کار به من کمک می کند."},{"de":"Wir gehen mit den Kollegen essen.","en":"We're going out to eat with our colleagues.","ru":"Мы идём обедать с коллегами.","vi":"Chúng tôi sẽ đi ăn tối với đồng nghiệp của chúng tôi.","fa":"با همکارانمان برای شام بیرون می رویم."}]},{"word":"die Kolonie","en":"colony","ru":"колония","vi":"thuộc địa","fa":"the colony","examples":[{"de":"Das Land besaß früher viele Kolonien in Afrika.","en":"The country once owned many colonies in Africa.","ru":"Раньше у страны было много колоний в Африке.","vi":"Đất nước từng có nhiều thuộc địa ở Châu Phi.","fa":"این کشور قبلاً مستعمرات زیادی در آفریقا داشت."},{"de":"Die Kolonie kämpfte lange für ihre Unabhängigkeit.","en":"The colony fought for a long time for its independence.","ru":"Колония долго боролась за свою независимость.","vi":"Thuộc địa đã chiến đấu giành độc lập trong một thời gian dài.","fa":"این مستعمره مدتها برای استقلال خود جنگید."},{"de":"In der Kolonie wurden die Menschen ausgebeutet.","en":"In the colony the people were exploited.","ru":"В колонии людей эксплуатировали.","vi":"Người dân bị bóc lột ở thuộc địa.","fa":"مردم در مستعمره مورد استثمار قرار گرفتند."}]},{"word":"komisch","en":"strange, odd; funny","ru":"странный; смешной","vi":"buồn cười","fa":"خنده دار","examples":[{"de":"Das ist komisch, die Tür war doch verschlossen.","en":"That's strange, the door was locked though.","ru":"Странно, дверь ведь была заперта.","vi":"Thật kỳ lạ, cửa đã bị khóa.","fa":"عجیب است، در قفل بود."},{"de":"Er hat einen komischen Witz erzählt.","en":"He told a funny joke.","ru":"Он рассказал смешную шутку.","vi":"Anh kể một chuyện vui.","fa":"یه جوک بامزه گفت"}]},{"word":"kommen","en":"to come","ru":"приходить, приезжать","vi":"đến","fa":"بیا","examples":[{"de":"Er kommt jeden Tag pünktlich zur Arbeit.","en":"He comes to work on time every day.","ru":"Он каждый день приходит на работу вовремя.","vi":"Anh ấy đến làm việc đúng giờ mỗi ngày.","fa":"او هر روز سر وقت سر کار می آید."},{"de":"Woher kommst du?","en":"Where are you from?","ru":"Откуда ты?","vi":"Bạn đến từ đâu?","fa":"شما از کجا می آیید؟"}]},{"word":"kommentieren","en":"to comment on something","ru":"комментировать что-либо","vi":"bình luận","fa":"نظر دادن","examples":[{"de":"Man kann Posts liken, kommentieren und teilen.","en":"You can like, comment on and share posts.","ru":"Постам можно ставить лайки, комментировать их и делиться ими.","vi":"Bạn có thể thích, bình luận và chia sẻ bài viết.","fa":"می توانید پست ها را لایک کنید، نظر بدهید و به اشتراک بگذارید."},{"de":"Bitte kommentiere meinen neuen Beitrag, wenn du Zeit hast.","en":"Please comment on my new post if you have time.","ru":"Прокомментируй, пожалуйста, мой новый пост, если будет время.","vi":"Hãy bình luận về bài viết mới của tôi nếu bạn có thời gian.","fa":"لطفا اگر وقت دارید در مورد پست جدید من نظر دهید."},{"de":"Im Internet kommentieren viele Menschen sehr unhöflich.","en":"On the internet many people comment very rudely.","ru":"В интернете многие комментируют очень грубо.","vi":"Nhiều người đưa ra những bình luận rất thô lỗ trên internet.","fa":"بسیاری از مردم نظرات بسیار بی ادبانه ای در اینترنت می دهند."}]},{"word":"Das kommt darauf an","en":"That depends (non-committal)","ru":"Это смотря как / зависит (уклончиво)","vi":"Điều đó phụ thuộc","fa":"این بستگی دارد","examples":[{"de":"Das kommt darauf an, wie viel es kostet.","en":"That depends on how much it costs.","ru":"Это зависит от того, сколько это стоит.","vi":"Điều đó phụ thuộc vào chi phí bao nhiêu.","fa":"این بستگی به هزینه آن دارد."}]},{"word":"die Kommunikation","en":"communication","ru":"коммуникация, общение","vi":"sự giao tiếp","fa":"ارتباط","examples":[{"de":"Gute Kommunikation ist im Team sehr wichtig.","en":"Good communication is very important in a team.","ru":"Хорошая коммуникация очень важна в команде.","vi":"Giao tiếp tốt là rất quan trọng trong một nhóm.","fa":"ارتباط خوب در یک تیم بسیار مهم است."},{"de":"Die Kommunikation zwischen den Abteilungen läuft über E-Mail.","en":"Communication between the departments takes place via email.","ru":"Общение между отделами происходит по электронной почте.","vi":"Việc liên lạc giữa các phòng ban diễn ra thông qua email.","fa":"ارتباط بین بخش ها از طریق ایمیل انجام می شود."}]},{"word":"die Komödie","en":"comedy","ru":"комедия","vi":"hài kịch","fa":"کمدی","examples":[{"de":"Gestern Abend haben wir uns eine lustige Komödie im Kino angesehen.","en":"Last night we watched a funny comedy at the cinema.","ru":"Вчера вечером мы посмотрели в кино смешную комедию.","vi":"Tối qua chúng tôi đã xem một bộ phim hài vui nhộn ở rạp chiếu phim.","fa":"دیشب یه کمدی خنده دار تو سینما دیدیم."},{"de":"Diese Komödie hat mich von Anfang bis Ende zum Lachen gebracht.","en":"This comedy made me laugh from start to finish.","ru":"Эта комедия смешила меня от начала до конца.","vi":"Bộ phim hài này đã khiến tôi cười từ đầu đến cuối.","fa":"این کمدی من را از اول تا آخر خنداند."},{"de":"Im Theater wird nächste Woche eine klassische Komödie aufgeführt.","en":"A classic comedy is being performed at the theatre next week.","ru":"На следующей неделе в театре ставят классическую комедию.","vi":"Một vở hài kịch kinh điển sẽ được trình diễn tại rạp vào tuần tới.","fa":"یک کمدی کلاسیک هفته آینده در تئاتر اجرا می شود."}]},{"word":"kompetent","en":"competent, capable","ru":"компетентный, знающий","vi":"có thẩm quyền","fa":"صالح","examples":[{"de":"Sie ist eine sehr kompetente Ärztin.","en":"She is a very competent doctor.","ru":"Она очень компетентный врач.","vi":"Cô ấy là một bác sĩ rất có năng lực.","fa":"او یک دکتر بسیار ماهر است."},{"de":"Der Berater hat uns kompetent geholfen.","en":"The adviser helped us competently.","ru":"Консультант грамотно нам помог.","vi":"Nhà tư vấn đã giúp chúng tôi một cách thành thạo.","fa":"مشاور به خوبی به ما کمک کرد."},{"de":"Für diese Aufgabe brauchen wir kompetente Mitarbeiter.","en":"For this task we need competent staff.","ru":"Для этой задачи нам нужны компетентные сотрудники.","vi":"Chúng tôi cần nhân viên có năng lực cho nhiệm vụ này.","fa":"برای این کار به کارمندان شایسته نیاز داریم."}]},{"word":"komplett","en":"complete","ru":"полный, целиком","vi":"hoàn thành","fa":"کامل","examples":[{"de":"Das Formular muss komplett ausgefüllt werden.","en":"The form must be filled out completely.","ru":"Бланк нужно заполнить полностью.","vi":"Mẫu đơn phải được điền đầy đủ.","fa":"فرم باید به طور کامل پر شود."},{"de":"Die Wohnung wird komplett renoviert.","en":"The apartment is being completely renovated.","ru":"Квартира ремонтируется полностью.","vi":"Căn hộ đang được cải tạo lại hoàn toàn.","fa":"آپارتمان در حال بازسازی کامل است."}]},{"word":"kompliziert","en":"complicated","ru":"сложный","vi":"phức tạp","fa":"پیچیده","examples":[{"de":"Die Aufgabe ist ziemlich kompliziert.","en":"The task is quite complicated.","ru":"Задача довольно сложная.","vi":"Nhiệm vụ khá phức tạp.","fa":"کار کاملاً پیچیده است."},{"de":"Er erklärt alles viel zu kompliziert.","en":"He explains everything much too complicatedly.","ru":"Он объясняет всё слишком сложно.","vi":"Er erklärt alles viel zu kompliziert.","fa":"او همه چیز را با عبارات بسیار پیچیده توضیح می دهد."}]},{"word":"der Kompromiss","en":"compromise","ru":"компромисс","vi":"sự thỏa hiệp","fa":"سازش","examples":[{"de":"Am Ende haben wir einen Kompromiss gefunden.","en":"In the end we found a compromise.","ru":"В конце концов мы нашли компромисс.","vi":"Cuối cùng chúng tôi đã tìm thấy một sự thỏa hiệp.","fa":"در پایان ما یک مصالحه پیدا کردیم."},{"de":"Sie mussten einen Kompromiss eingehen.","en":"They had to make a compromise.","ru":"Им пришлось пойти на компромисс.","vi":"Họ đã phải thỏa hiệp.","fa":"آنها باید سازش می کردند."}]},{"word":"die Kondition","en":"fitness; (physical) condition; terms","ru":"физическая форма; выносливость; (мн.) условия","vi":"điều kiện","fa":"شرط","examples":[{"de":"Durch das tägliche Joggen hat sich meine Kondition deutlich verbessert.","en":"Thanks to daily jogging, my fitness has improved noticeably.","ru":"Благодаря ежедневным пробежкам моя форма заметно улучшилась.","vi":"Chạy bộ hàng ngày đã cải thiện đáng kể tình trạng của tôi.","fa":"دویدن روزانه به طور قابل توجهی وضعیت من را بهبود بخشیده است."},{"de":"Für einen Marathon braucht man eine sehr gute Kondition.","en":"For a marathon you need very good fitness.","ru":"Для марафона нужна очень хорошая физическая форма.","vi":"Bạn cần phải có thể trạng rất tốt để tham gia chạy marathon.","fa":"برای یک ماراتن باید در شرایط بدنی بسیار خوبی باشید."},{"de":"Nach der langen Pause war seine Kondition leider nicht mehr so gut.","en":"After the long break his fitness was unfortunately no longer so good.","ru":"После долгого перерыва его форма, к сожалению, была уже не такой хорошей.","vi":"Đáng tiếc, sau thời gian dài nghỉ ngơi, tình trạng của anh không còn tốt nữa.","fa":"متأسفانه پس از وقفه طولانی، وضعیت او دیگر چندان خوب نبود."}]},{"word":"die Konferenz","en":"conference","ru":"конференция","vi":"hội nghị","fa":"کنفرانس","examples":[{"de":"Die Konferenz findet nächste Woche in Berlin statt.","en":"The conference takes place in Berlin next week.","ru":"Конференция состоится на следующей неделе в Берлине.","vi":"Hội nghị sẽ diễn ra vào tuần tới tại Berlin.","fa":"این کنفرانس هفته آینده در برلین برگزار می شود."},{"de":"Sie hält einen Vortrag auf der Konferenz.","en":"She is giving a talk at the conference.","ru":"Она выступит с докладом на конференции.","vi":"Cô ấy phát biểu tại hội nghị.","fa":"او در کنفرانس سخنرانی می کند."}]},{"word":"die Konfitüre","en":"jam","ru":"джем, варенье","vi":"mứt","fa":"مربا","examples":[{"de":"Zum Frühstück gibt es Brötchen mit Konfitüre.","en":"For breakfast there are rolls with jam.","ru":"На завтрак булочки с джемом.","vi":"Bữa sáng có bánh cuốn với mứt.","fa":"برای صبحانه رول هایی با مربا وجود دارد."},{"de":"Sie kocht die Konfitüre selbst aus Erdbeeren.","en":"She makes the jam herself from strawberries.","ru":"Она сама варит джем из клубники.","vi":"She makes the jam herself from strawberries.","fa":"مربا را خودش از توت فرنگی درست می کند."}]},{"word":"der Konflikt","en":"conflict","ru":"конфликт","vi":"cuộc xung đột","fa":"درگیری","examples":[{"de":"Zwischen den beiden Ländern gibt es einen Konflikt.","en":"There is a conflict between the two countries.","ru":"Между двумя странами существует конфликт.","vi":"Giữa hai nước đang có xung đột.","fa":"درگیری بین دو کشور وجود دارد."},{"de":"Wir konnten den Konflikt friedlich lösen.","en":"We were able to resolve the conflict peacefully.","ru":"Мы смогли мирно разрешить конфликт.","vi":"Chúng tôi đã có thể giải quyết xung đột một cách hòa bình.","fa":"ما توانستیم درگیری را به صورت مسالمت آمیز حل کنیم."}]},{"word":"der König","en":"king","ru":"король","vi":"nhà vua","fa":"پادشاه","examples":[{"de":"Der König regierte das Land viele Jahre.","en":"The king ruled the country for many years.","ru":"Король правил страной много лет.","vi":"Nhà vua cai trị đất nước trong nhiều năm.","fa":"شاه سالها بر کشور حکومت کرد."},{"de":"Im Märchen heiratet die Prinzessin den König.","en":"In the fairy tale, the princess marries the king.","ru":"В сказке принцесса выходит замуж за короля.","vi":"Trong truyện cổ tích, công chúa kết hôn với nhà vua.","fa":"در یک افسانه، شاهزاده خانم با پادشاه ازدواج می کند."}]},{"word":"die Konkurrenz","en":"competition","ru":"конкуренция","vi":"the competition","fa":"رقابت","examples":[{"de":"Die Konkurrenz auf dem Markt ist sehr groß.","en":"Competition in the market is very strong.","ru":"Конкуренция на рынке очень высока.","vi":"Sự cạnh tranh trên thị trường là rất cao.","fa":"رقابت در بازار بسیار بالاست."},{"de":"Unsere Firma hat viel Konkurrenz.","en":"Our company has a lot of competition.","ru":"У нашей фирмы много конкурентов.","vi":"Công ty chúng tôi có rất nhiều sự cạnh tranh.","fa":"شرکت ما رقابت زیادی دارد."}]},{"word":"können","en":"can, to be able to","ru":"мочь, уметь","vi":"có thể","fa":"می تواند","examples":[{"de":"Ich kann leider nicht kommen.","en":"Unfortunately I can't come.","ru":"К сожалению, я не могу прийти.","vi":"Thật không may là tôi không thể đến được.","fa":"متاسفانه نمیتونم بیام"},{"de":"Sie kann sehr gut schwimmen.","en":"She can swim very well.","ru":"Она очень хорошо умеет плавать.","vi":"Cô ấy có thể bơi rất giỏi.","fa":"او می تواند بسیار خوب شنا کند."}]},{"word":"Können Sie das bitte wiederholen?","en":"Could you please repeat that? (asking to repeat)","ru":"Не могли бы вы повторить? (просьба повторить)","vi":"Bạn có thể vui lòng lặp lại điều đó?","fa":"ممکن است لطفا آن را تکرار کنید؟","examples":[{"de":"Entschuldigung, können Sie das bitte wiederholen?","en":"Sorry, could you please repeat that?","ru":"Извините, не могли бы вы повторить?","vi":"Xin lỗi, bạn có thể nhắc lại được không?","fa":"ببخشید میشه لطفا تکرارش کنید؟"}]},{"word":"Könntest du mir bitte helfen?","en":"Could you please help me? (asking for help)","ru":"Не мог бы ты мне помочь? (просьба о помощи)","vi":"Bạn có thể vui lòng giúp tôi được không?","fa":"میشه لطفا کمکم کنید","examples":[{"de":"Könntest du mir bitte kurz helfen?","en":"Could you please help me for a moment?","ru":"Не мог бы ты мне ненадолго помочь?","vi":"Bạn có thể vui lòng giúp tôi một thời gian ngắn?","fa":"میشه لطفا مختصر راهنماییم کنید"}]},{"word":"das Konsulat","en":"consulate","ru":"консульство","vi":"lãnh sự quán","fa":"کنسولگری","examples":[{"de":"Er muss zum Konsulat, um ein Visum zu beantragen.","en":"He has to go to the consulate to apply for a visa.","ru":"Ему нужно в консульство, чтобы подать заявление на визу.","vi":"Anh ta phải đến lãnh sự quán để xin thị thực.","fa":"او باید برای درخواست ویزا به کنسولگری برود."},{"de":"Das Konsulat hilft Bürgern im Ausland.","en":"The consulate helps citizens abroad.","ru":"Консульство помогает гражданам за рубежом.","vi":"Lãnh sự quán giúp đỡ công dân ở nước ngoài.","fa":"کنسولگری به شهروندان خارج از کشور کمک می کند."}]},{"word":"der Konsum","en":"consumption","ru":"потребление, расход","vi":"sự tiêu thụ","fa":"مصرف","examples":[{"de":"Der Konsum von zu viel Zucker ist nicht gut für die Gesundheit.","en":"The consumption of too much sugar is not good for one's health.","ru":"Потребление слишком большого количества сахара вредно для здоровья.","vi":"Tiêu thụ quá nhiều đường sẽ không tốt cho sức khỏe của bạn.","fa":"مصرف زیاد شکر برای سلامتی شما مفید نیست."},{"de":"In den Ferien steigt der Konsum von Eis deutlich an.","en":"During the holidays the consumption of ice cream rises noticeably.","ru":"В каникулы потребление мороженого заметно растёт.","vi":"Tiêu thụ kem tăng đáng kể trong những ngày nghỉ lễ.","fa":"مصرف بستنی در تعطیلات به میزان قابل توجهی افزایش می یابد."},{"de":"Ein bewusster Konsum schützt die Umwelt.","en":"Conscious consumption protects the environment.","ru":"Осознанное потребление бережёт окружающую среду.","vi":"Tiêu dùng có ý thức bảo vệ môi trường.","fa":"مصرف آگاهانه از محیط زیست محافظت می کند."}]},{"word":"konsumieren","en":"to consume","ru":"потреблять","vi":"tiêu thụ","fa":"مصرف کنند","examples":[{"de":"Viele Menschen konsumieren zu viel Zucker.","en":"Many people consume too much sugar.","ru":"Многие люди потребляют слишком много сахара.","vi":"Nhiều người tiêu thụ quá nhiều đường.","fa":"بسیاری از مردم بیش از حد قند مصرف می کنند."},{"de":"Man sollte Alkohol nur in Maßen konsumieren.","en":"One should only consume alcohol in moderation.","ru":"Алкоголь следует потреблять только в меру.","vi":"Man sollte Alkohol nur ở Maßen konsumieren.","fa":"فقط باید الکل را در حد اعتدال مصرف کنید."}]},{"word":"der Kontakt","en":"contact","ru":"контакт","vi":"liên hệ","fa":"تماس","examples":[{"de":"Wir haben seit Jahren keinen Kontakt mehr.","en":"We haven't had any contact for years.","ru":"У нас уже много лет нет контакта.","vi":"Chúng tôi đã không liên lạc trong nhiều năm.","fa":"ما سال هاست که هیچ ارتباطی با هم نداریم."},{"de":"Bitte nehmen Sie Kontakt mit uns auf.","en":"Please get in touch with us.","ru":"Пожалуйста, свяжитесь с нами.","vi":"Vui lòng liên hệ với chúng tôi.","fa":"لطفا با ما تماس بگیرید."}]},{"word":"das Konto","en":"(bank) account","ru":"счёт (банковский)","vi":"tài khoản","fa":"حساب کاربری","examples":[{"de":"Ich habe mein Konto bei der Sparkasse.","en":"I have my account at the savings bank.","ru":"У меня счёт в сберегательной кассе.","vi":"Tôi có tài khoản ở ngân hàng tiết kiệm.","fa":"من حسابم را در بانک پس انداز دارم."},{"de":"Das Geld wurde auf mein Konto überwiesen.","en":"The money was transferred to my account.","ru":"Деньги были переведены на мой счёт.","vi":"Tiền đã được chuyển vào tài khoản của tôi.","fa":"پول به حساب من واریز شد."}]},{"word":"die Kontrolle","en":"check; control","ru":"контроль, проверка","vi":"sự kiểm soát","fa":"کنترل","examples":[{"de":"An der Grenze gab es heute eine strenge Kontrolle der Pässe.","en":"At the border there was a strict check of passports today.","ru":"На границе сегодня была строгая проверка паспортов.","vi":"Ngày nay, hộ chiếu được kiểm soát chặt chẽ ở biên giới.","fa":"کنترل شدید گذرنامه ها امروز در مرز بود."},{"de":"Der Lehrer behält die Kontrolle über die laute Klasse.","en":"The teacher keeps control over the noisy class.","ru":"Учитель сохраняет контроль над шумным классом.","vi":"Giáo viên duy trì quyền kiểm soát lớp học ồn ào.","fa":"معلم کنترل کلاس پر سر و صدا را حفظ می کند."},{"de":"Bei der Kontrolle der Tickets hatte ich meins leider vergessen.","en":"During the ticket check I had unfortunately forgotten mine.","ru":"При проверке билетов я, к сожалению, забыл свой.","vi":"Thật không may, tôi đã quên của tôi khi kiểm tra vé.","fa":"متأسفانه وقتی بلیط ها را چک کردم، مال خودم را فراموش کردم."}]},{"word":"kontrollieren","en":"to check, control","ru":"проверять, контролировать","vi":"kiểm soát","fa":"کنترل کنید","examples":[{"de":"Der Lehrer kontrolliert die Hausaufgaben.","en":"The teacher checks the homework.","ru":"Учитель проверяет домашнее задание.","vi":"The teacher checks the homework.","fa":"معلم تکالیف را بررسی می کند."},{"de":"An der Grenze wurden unsere Pässe kontrolliert.","en":"Our passports were checked at the border.","ru":"На границе проверили наши паспорта.","vi":"Hộ chiếu của chúng tôi đã được kiểm tra ở biên giới.","fa":"پاسپورت های ما در مرز چک شد."}]},{"word":"die Konzentration","en":"concentration","ru":"концентрация, сосредоточенность","vi":"sự tập trung","fa":"غلظت","examples":[{"de":"Schwierige Haltungen verlangen volle Konzentration.","en":"Difficult poses demand full concentration.","ru":"Сложные позы требуют полной концентрации.","vi":"Những tư thế khó đòi hỏi sự tập trung cao độ.","fa":"وضعیت های سخت نیاز به تمرکز کامل دارند."},{"de":"Yoga verbessert meine Konzentration beim Lernen.","en":"Yoga improves my concentration while studying.","ru":"Йога улучшает мою концентрацию при учёбе.","vi":"Yoga cải thiện sự tập trung của tôi khi học tập.","fa":"یوگا تمرکز من را هنگام مطالعه بهبود می بخشد."},{"de":"Verliere die Konzentration nicht, wenn du das Gleichgewicht hältst.","en":"Don't lose concentration while you hold the balance.","ru":"Не теряй концентрацию, удерживая равновесие.","vi":"Đừng mất tập trung trong khi duy trì sự cân bằng của bạn.","fa":"با حفظ تعادل تمرکز خود را از دست ندهید."}]},{"word":"konzentrieren","en":"to concentrate","ru":"сосредотачиваться, концентрироваться","vi":"tập trung","fa":"تمرکز کنید","examples":[{"de":"Konzentriere dich nur auf deinen Atem.","en":"Concentrate only on your breath.","ru":"Сосредоточься только на своём дыхании.","vi":"Chỉ cần tập trung vào hơi thở của bạn.","fa":"فقط روی تنفس خود تمرکز کنید."},{"de":"Beim Balancieren musst du dich gut konzentrieren.","en":"When balancing you have to concentrate well.","ru":"При балансировании нужно хорошо концентрироваться.","vi":"Bạn phải tập trung tốt khi giữ thăng bằng.","fa":"هنگام حفظ تعادل باید به خوبی تمرکز کنید."},{"de":"Sie konzentrierte sich auf jede einzelne Bewegung.","en":"She concentrated on every single movement.","ru":"Она сосредоточилась на каждом отдельном движении.","vi":"Cô tập trung vào từng động tác.","fa":"او روی تک تک حرکات متمرکز بود."}]},{"word":"das Konzert","en":"concert","ru":"концерт","vi":"buổi hòa nhạc","fa":"کنسرت","examples":[{"de":"Wir waren gestern auf einem tollen Konzert.","en":"We were at a great concert yesterday.","ru":"Вчера мы были на отличном концерте.","vi":"Chúng tôi đã đi đến một buổi hòa nhạc tuyệt vời ngày hôm qua.","fa":"دیروز به یک کنسرت عالی رفتیم."},{"de":"Die Band gibt nächsten Monat ein Konzert.","en":"The band is giving a concert next month.","ru":"В следующем месяце группа даёт концерт.","vi":"Ban nhạc sẽ tổ chức buổi hòa nhạc vào tháng tới.","fa":"گروه در ماه آینده کنسرت برگزار می کند."}]},{"word":"der Kopf","en":"head","ru":"голова","vi":"cái đầu","fa":"سر","examples":[{"de":"Mir tut der Kopf weh.","en":"My head hurts.","ru":"У меня болит голова.","vi":"Đầu tôi đau quá.","fa":"سرم درد میکنه"},{"de":"Er schüttelte den Kopf.","en":"He shook his head.","ru":"Он покачал головой.","vi":"Anh lắc đầu.","fa":"سرش را تکان داد."}]},{"word":"das Kopfrechnen","en":"mental arithmetic","ru":"устный счёт","vi":"tính nhẩm","fa":"حساب ذهنی","examples":[{"de":"Im Kopfrechnen war sie schon als Kind sehr schnell.","en":"She was very fast at mental arithmetic even as a child.","ru":"В устном счёте она была очень быстрой уже в детстве.","vi":"Ngay từ khi còn nhỏ, cô đã rất nhanh nhạy trong việc tính nhẩm.","fa":"او حتی در کودکی در محاسبات ذهنی بسیار سریع بود."},{"de":"Kopfrechnen hilft beim Einkaufen im Supermarkt.","en":"Mental arithmetic helps when shopping in the supermarket.","ru":"Устный счёт помогает при покупках в супермаркете.","vi":"Tính nhẩm giúp ích khi mua sắm trong siêu thị.","fa":"حساب ذهنی هنگام خرید در سوپرمارکت کمک می کند."},{"de":"Der Lehrer übte jeden Tag fünf Minuten Kopfrechnen.","en":"The teacher practised five minutes of mental arithmetic every day.","ru":"Учитель каждый день упражнялся пять минут в устном счёте.","vi":"Giáo viên luyện tập tính nhẩm trong năm phút mỗi ngày.","fa":"معلم هر روز پنج دقیقه حساب ذهنی را تمرین می کرد."}]},{"word":"die Kopie","en":"copy","ru":"копия","vi":"bản sao","fa":"کپی","examples":[{"de":"Können Sie mir bitte eine Kopie dieses Dokuments machen?","en":"Could you please make me a copy of this document?","ru":"Не могли бы вы сделать мне копию этого документа?","vi":"Bạn có thể cho tôi xin một bản sao của tài liệu này được không?","fa":"آیا می توانید یک کپی از این سند را برای من تهیه کنید؟"},{"de":"Ich habe eine Kopie meines Vertrags zu Hause aufbewahrt.","en":"I have kept a copy of my contract at home.","ru":"Я сохранил копию своего договора дома.","vi":"Tôi đã giữ một bản sao hợp đồng của tôi ở nhà.","fa":"من یک نسخه از قراردادم را در خانه نگه داشته ام."},{"de":"Diese Kopie ist leider zu dunkel geworden.","en":"This copy has unfortunately come out too dark.","ru":"Эта копия, к сожалению, получилась слишком тёмной.","vi":"Thật không may, bản sao này đã trở nên quá tối.","fa":"متاسفانه این کپی خیلی تاریک شده است."}]},{"word":"kopieren","en":"to copy","ru":"копировать","vi":"sao chép","fa":"کپی کنید","examples":[{"de":"Kannst du diese Seite für mich kopieren?","en":"Can you copy this page for me?","ru":"Можешь скопировать для меня эту страницу?","vi":"Can you copy this page for me?","fa":"آیا می توانید این صفحه را برای من کپی کنید؟"},{"de":"Er hat den Text einfach kopiert.","en":"He simply copied the text.","ru":"Он просто скопировал текст.","vi":"Anh ấy chỉ đơn giản là sao chép văn bản.","fa":"او به سادگی متن را کپی کرد."}]},{"word":"der Kopierer","en":"photocopier","ru":"копировальный аппарат, ксерокс","vi":"máy photocopy","fa":"دستگاه کپی","examples":[{"de":"Der Kopierer im Büro ist schon wieder kaputt.","en":"The photocopier in the office is broken again.","ru":"Копировальный аппарат в офисе снова сломан.","vi":"Máy photocopy ở văn phòng lại bị hỏng.","fa":"دستگاه کپی در دفتر دوباره خراب است."},{"de":"Bitte legen Sie das Papier richtig in den Kopierer ein.","en":"Please load the paper into the photocopier correctly.","ru":"Пожалуйста, правильно заправьте бумагу в копировальный аппарат.","vi":"Hãy nạp giấy vào máy photocopy một cách chính xác.","fa":"لطفاً کاغذ را به درستی در دستگاه کپی قرار دهید."},{"de":"Ich brauche zehn Minuten, um alle Unterlagen am Kopierer zu vervielfältigen.","en":"I need ten minutes to duplicate all the documents at the photocopier.","ru":"Мне нужно десять минут, чтобы размножить все документы на копировальном аппарате.","vi":"Tôi phải mất mười phút để sao chép tất cả tài liệu trên máy photocopy.","fa":"ده دقیقه طول می کشد تا تمام اسناد روی دستگاه کپی را کپی کنم."}]},{"word":"der Körper","en":"body","ru":"тело","vi":"cơ thể","fa":"بدن","examples":[{"de":"Sport ist gut für den Körper.","en":"Sport is good for the body.","ru":"Спорт полезен для тела.","vi":"Thể thao tốt cho cơ thể.","fa":"ورزش برای بدن مفید است."},{"de":"Nach dem Training spürte sie jeden Muskel im Körper.","en":"After the workout she felt every muscle in her body.","ru":"После тренировки она чувствовала каждую мышцу тела.","vi":"Sau khi tập luyện, cô cảm nhận được từng cơ bắp trên cơ thể mình.","fa":"او پس از تمرین، تمام ماهیچه های بدنش را حس کرد."}]},{"word":"körperlich","en":"physical, bodily","ru":"физический, телесный","vi":"thể chất","fa":"فیزیکی","examples":[{"de":"Die Arbeit ist körperlich sehr anstrengend.","en":"The work is physically very demanding.","ru":"Работа физически очень тяжёлая.","vi":"Công việc đòi hỏi rất nhiều về thể chất.","fa":"کار از نظر فیزیکی بسیار سخت است."},{"de":"Regelmäßiger Sport hält dich körperlich fit.","en":"Regular exercise keeps you physically fit.","ru":"Регулярный спорт держит в хорошей физической форме.","vi":"Tập thể dục thường xuyên giúp bạn có vóc dáng cân đối.","fa":"ورزش منظم شما را از نظر بدنی آماده نگه می دارد."},{"de":"Er hat keine körperlichen Beschwerden.","en":"He has no physical complaints.","ru":"У него нет никаких физических жалоб.","vi":"Anh ấy không có khiếu nại về thể chất.","fa":"او هیچ شکایت جسمی ندارد."}]},{"word":"korrekt","en":"correct","ru":"правильный, корректный","vi":"đúng","fa":"درست است","examples":[{"de":"Ihre Antwort war völlig korrekt.","en":"Her answer was completely correct.","ru":"Её ответ был полностью правильным.","vi":"Câu trả lời của bạn đã hoàn toàn chính xác.","fa":"پاسخ شما کاملا درست بود"},{"de":"Bitte füllen Sie das Formular korrekt aus.","en":"Please fill out the form correctly.","ru":"Пожалуйста, заполните бланк правильно.","vi":"Vui lòng điền vào mẫu một cách chính xác.","fa":"لطفا فرم را به درستی پر کنید."}]},{"word":"der Korridor","en":"corridor, hallway","ru":"коридор","vi":"the corridor","fa":"راهرو","examples":[{"de":"Die Zimmer liegen alle am selben Korridor.","en":"All the rooms are on the same corridor.","ru":"Все комнаты расположены в одном коридоре.","vi":"Các phòng đều nằm trên cùng một hành lang.","fa":"اتاق ها همه در یک راهرو قرار دارند."},{"de":"Im Korridor hängen viele Bilder.","en":"Many pictures hang in the corridor.","ru":"В коридоре висит много картин.","vi":"Có rất nhiều bức tranh được treo ở hành lang.","fa":"عکس های زیادی در راهرو آویزان است."}]},{"word":"korrigieren","en":"to correct","ru":"исправлять","vi":"đúng","fa":"درست است","examples":[{"de":"Der Lehrer korrigiert die Klassenarbeiten am Wochenende.","en":"The teacher corrects the tests over the weekend.","ru":"Учитель проверяет контрольные на выходных.","vi":"Giáo viên sửa bài tập của lớp vào cuối tuần.","fa":"معلم کار کلاس را در آخر هفته تصحیح می کند."},{"de":"Kannst du meinen Fehler korrigieren?","en":"Can you correct my mistake?","ru":"Можешь исправить мою ошибку?","vi":"Bạn có thể sửa lỗi của tôi không?","fa":"آیا می توانید اشتباه من را اصلاح کنید؟"}]},{"word":"kosmisch","en":"cosmic","ru":"космический","vi":"vũ trụ","fa":"کیهانی","examples":[{"de":"Kosmische Strahlung trifft ständig auf die Erde.","en":"Cosmic radiation constantly hits the Earth.","ru":"Космическое излучение постоянно достигает Земли.","vi":"Các tia vũ trụ liên tục chiếu vào Trái đất.","fa":"پرتوهای کیهانی دائماً به زمین برخورد می کنند."},{"de":"Diese Bilder zeigen ein faszinierendes kosmisches Schauspiel.","en":"These images show a fascinating cosmic spectacle.","ru":"Эти снимки показывают завораживающее космическое зрелище.","vi":"Những hình ảnh này cho thấy một cảnh tượng vũ trụ hấp dẫn.","fa":"این تصاویر یک منظره کیهانی جذاب را نشان می دهد."},{"de":"Die kosmischen Entfernungen sind kaum vorstellbar.","en":"The cosmic distances are barely imaginable.","ru":"Космические расстояния едва вообразимы.","vi":"Khoảng cách vũ trụ thật khó tưởng tượng.","fa":"تصور فاصله های کیهانی سخت است."}]},{"word":"kosten","en":"to cost","ru":"стоить","vi":"chi phí","fa":"هزینه","examples":[{"de":"Wie viel kostet das Buch?","en":"How much does the book cost?","ru":"Сколько стоит эта книга?","vi":"Cuốn sách có giá bao nhiêu?","fa":"قیمت کتاب چقدر است؟"},{"de":"Die Reparatur hat viel Geld gekostet.","en":"The repair cost a lot of money.","ru":"Ремонт стоил много денег.","vi":"Việc sửa chữa tốn rất nhiều tiền.","fa":"تعمیر هزینه زیادی دارد."}]},{"word":"kostenlos","en":"free (of charge)","ru":"бесплатный","vi":"miễn phí","fa":"رایگان","examples":[{"de":"Der Eintritt ins Museum ist heute kostenlos.","en":"Admission to the museum is free today.","ru":"Вход в музей сегодня бесплатный.","vi":"Vào cửa bảo tàng ngày hôm nay là miễn phí.","fa":"ورود به موزه امروز رایگان است."},{"de":"Die App kann man kostenlos herunterladen.","en":"You can download the app for free.","ru":"Приложение можно скачать бесплатно.","vi":"Ứng dụng có thể được tải xuống miễn phí.","fa":"برنامه را می توان به صورت رایگان دانلود کرد."}]},{"word":"der Kostenvoranschlag","en":"cost estimate; quotation","ru":"смета, предварительный расчёт стоимости","vi":"ước tính chi phí","fa":"برآورد هزینه","examples":[{"de":"Bevor wir das Auto reparieren lassen, brauchen wir einen Kostenvoranschlag.","en":"Before we have the car repaired, we need a cost estimate.","ru":"Прежде чем отдавать машину в ремонт, нам нужна смета.","vi":"Trước khi sửa chữa xe, chúng ta cần ước tính chi phí.","fa":"قبل از اینکه ماشین را تعمیر کنیم، به برآورد هزینه نیاز داریم."},{"de":"Die Werkstatt hat mir einen Kostenvoranschlag über 300 Euro gemacht.","en":"The garage gave me a cost estimate of 300 euros.","ru":"Автомастерская составила мне смету на 300 евро.","vi":"Hội thảo đã cho tôi ước tính chi phí là 300 euro.","fa":"کارگاه به من برآورد هزینه 300 یورو را داد."},{"de":"Können Sie mir bitte einen schriftlichen Kostenvoranschlag schicken?","en":"Could you please send me a written quotation?","ru":"Не могли бы вы прислать мне письменную смету?","vi":"Bạn có thể vui lòng gửi cho tôi một bản ước tính bằng văn bản?","fa":"آیا می توانید یک برآورد کتبی برای من ارسال کنید؟"}]},{"word":"das Kostüm","en":"costume; (women's) suit","ru":"костюм (маскарадный); женский костюм","vi":"trang phục","fa":"لباس","examples":[{"de":"Zu Karneval trägt sie ein buntes Kostüm.","en":"At carnival she wears a colorful costume.","ru":"На карнавале она носит яркий костюм.","vi":"Cô mặc một bộ trang phục đầy màu sắc tại lễ hội.","fa":"او در کارناوال یک لباس رنگارنگ می پوشد."},{"de":"Sie kaufte sich ein neues Kostüm für die Arbeit.","en":"She bought herself a new suit for work.","ru":"Она купила себе новый костюм для работы.","vi":"Cô ấy mua một bộ trang phục mới để đi làm.","fa":"او یک لباس جدید برای کار خرید."}]},{"word":"die Kraft","en":"strength, power","ru":"сила","vi":"sức mạnh","fa":"قدرت","examples":[{"de":"Er hat nicht mehr genug Kraft zum Heben.","en":"He no longer has enough strength to lift it.","ru":"У него больше не хватает сил, чтобы поднять это.","vi":"Anh không còn đủ sức để nâng nữa.","fa":"او دیگر قدرت کافی برای بلند کردن ندارد."},{"de":"Die Kraft des Windes war beeindruckend.","en":"The power of the wind was impressive.","ru":"Сила ветра была впечатляющей.","vi":"Sức mạnh của gió thật ấn tượng.","fa":"قدرت باد چشمگیر بود."}]},{"word":"das Kraftfahrzeug","en":"motor vehicle","ru":"автотранспортное средство","vi":"chiếc xe cơ giới","fa":"وسیله نقلیه موتوری","examples":[{"de":"Jedes Kraftfahrzeug braucht ein amtliches Kennzeichen.","en":"Every motor vehicle needs an official license plate.","ru":"Каждое автотранспортное средство должно иметь номерной знак.","vi":"Mọi phương tiện cơ giới đều cần có biển số chính thức.","fa":"هر وسیله نقلیه موتوری نیاز به پلاک رسمی دارد."},{"de":"Das Kraftfahrzeug wurde beim TÜV geprüft.","en":"The motor vehicle was inspected at the TÜV.","ru":"Автотранспортное средство прошло техосмотр.","vi":"Chiếc xe cơ giới đã được thử nghiệm bởi TÜV.","fa":"وسیله نقلیه موتوری توسط TÜV آزمایش شد."}]},{"word":"kräftig","en":"strong, powerful","ru":"сильный, крепкий; наваристый","vi":"mạnh mẽ","fa":"قوی","examples":[{"de":"Er hat sehr kräftige Arme.","en":"He has very strong arms.","ru":"У него очень сильные руки.","vi":"Anh ấy có cánh tay rất khỏe.","fa":"او بازوهای بسیار قوی دارد."},{"de":"Heute weht ein kräftiger Wind.","en":"A strong wind is blowing today.","ru":"Сегодня дует сильный ветер.","vi":"Hôm nay có gió thổi mạnh.","fa":"امروز باد شدیدی می وزد."},{"de":"Nach dem Sport esse ich gern etwas Kräftiges.","en":"After exercise I like to eat something hearty.","ru":"После спорта я люблю поесть чего-нибудь сытного.","vi":"Sau khi tập thể dục, tôi thích ăn thứ gì đó thịnh soạn.","fa":"بعد از ورزش، من دوست دارم یک چیز دلچسب بخورم."}]},{"word":"das Krafttraining","en":"strength training; weight training","ru":"силовая тренировка","vi":"rèn luyện sức mạnh","fa":"تمرین قدرتی","examples":[{"de":"Ich mache dreimal pro Woche Krafttraining im Fitnessstudio.","en":"I do strength training at the gym three times a week.","ru":"Я делаю силовые тренировки в тренажёрном зале трижды в неделю.","vi":"Tôi tập luyện sức mạnh trong phòng tập thể dục ba lần một tuần.","fa":"هفته ای سه بار در باشگاه تمرینات قدرتی انجام می دهم."},{"de":"Krafttraining hilft dabei, die Muskeln aufzubauen.","en":"Strength training helps to build up the muscles.","ru":"Силовая тренировка помогает наращивать мышцы.","vi":"Tập luyện sức mạnh giúp xây dựng cơ bắp.","fa":"تمرینات قدرتی به عضله سازی کمک می کند."},{"de":"Nach dem Krafttraining sind meine Arme ganz müde.","en":"After the weight training my arms are completely tired.","ru":"После силовой тренировки у меня совсем устали руки.","vi":"Sau khi tập luyện sức mạnh, cánh tay của tôi rất mỏi.","fa":"بعد از تمرینات قدرتی، بازوهایم بسیار خسته هستند."}]},{"word":"das Kraftwerk","en":"power plant","ru":"электростанция","vi":"nhà máy điện","fa":"نیروگاه","examples":[{"de":"Das Kraftwerk versorgt die ganze Region mit Strom.","en":"The power plant supplies the whole region with electricity.","ru":"Электростанция снабжает электричеством весь регион.","vi":"Nhà máy điện cung cấp điện cho toàn khu vực.","fa":"نیروگاه برق کل منطقه را تامین می کند."},{"de":"Ein neues Kraftwerk wird außerhalb der Stadt gebaut.","en":"A new power plant is being built outside the city.","ru":"За городом строится новая электростанция.","vi":"Một nhà máy điện mới đang được xây dựng bên ngoài thành phố.","fa":"یک نیروگاه جدید در خارج از شهر در حال ساخت است."}]},{"word":"krank","en":"sick, ill","ru":"больной","vi":"bị bệnh","fa":"بیمار","examples":[{"de":"Mein Sohn ist heute krank und bleibt zu Hause.","en":"My son is sick today and is staying home.","ru":"Мой сын сегодня болен и остаётся дома.","vi":"Hôm nay con trai tôi bị ốm và đang ở nhà.","fa":"پسرم امروز مریض است و در خانه است."},{"de":"Sie war letzte Woche schwer krank.","en":"She was seriously ill last week.","ru":"На прошлой неделе она была тяжело больна.","vi":"Tuần trước cô ấy bị ốm nặng.","fa":"او هفته گذشته به شدت بیمار بود."}]},{"word":"der Kranke","en":"sick person; patient","ru":"больной (человек)","vi":"người bệnh","fa":"فرد بیمار","examples":[{"de":"Der Kranke musste die ganze Woche im Bett bleiben.","en":"The sick man had to stay in bed all week.","ru":"Больной всю неделю должен был оставаться в постели.","vi":"Bệnh nhân phải nằm trên giường cả tuần.","fa":"بیمار باید تمام هفته را در رختخواب می ماند."},{"de":"Die Krankenschwester kümmert sich liebevoll um den Kranken.","en":"The nurse looks after the sick man with care.","ru":"Медсестра заботливо ухаживает за больным.","vi":"Cô y tá tận tình chăm sóc bệnh nhân.","fa":"پرستار با محبت از بیمار مراقبت می کند."},{"de":"Ein Kranker sollte sich viel ausruhen und genug trinken.","en":"A sick person should rest a lot and drink enough.","ru":"Больному следует много отдыхать и достаточно пить.","vi":"Người bệnh cần nghỉ ngơi nhiều và uống đủ nước.","fa":"فرد بیمار باید استراحت کافی داشته باشد و به اندازه کافی بنوشد."}]},{"word":"der Krankenpfleger","en":"(male) nurse","ru":"медбрат (санитар)","vi":"y tá","fa":"پرستار","examples":[{"de":"Mein Bruder arbeitet als Krankenpfleger im örtlichen Krankenhaus.","en":"My brother works as a nurse at the local hospital.","ru":"Мой брат работает медбратом в местной больнице.","vi":"Anh trai tôi làm y tá ở bệnh viện địa phương.","fa":"برادرم به عنوان پرستار در بیمارستان محلی کار می کند."},{"de":"Der Krankenpfleger gab dem Patienten seine Medikamente.","en":"The nurse gave the patient his medication.","ru":"Медбрат дал пациенту его лекарства.","vi":"Y tá đưa thuốc cho bệnh nhân.","fa":"پرستار داروهایش را به بیمار داد."},{"de":"Ein guter Krankenpfleger muss geduldig und freundlich sein.","en":"A good nurse must be patient and friendly.","ru":"Хороший медбрат должен быть терпеливым и приветливым.","vi":"Một y tá giỏi phải kiên nhẫn và tốt bụng.","fa":"یک پرستار خوب باید صبور و مهربان باشد."}]},{"word":"die Krankenschwester","en":"nurse","ru":"медсестра","vi":"y tá","fa":"پرستار","examples":[{"de":"Die Krankenschwester kümmert sich um die Patienten.","en":"The nurse takes care of the patients.","ru":"Медсестра заботится о пациентах.","vi":"Y tá chăm sóc bệnh nhân.","fa":"پرستار از بیماران مراقبت می کند."},{"de":"Sie möchte Krankenschwester werden.","en":"She wants to become a nurse.","ru":"Она хочет стать медсестрой.","vi":"Cô ấy muốn trở thành một y tá.","fa":"او می خواهد پرستار شود."}]},{"word":"der Krankenwagen","en":"ambulance","ru":"машина скорой помощи","vi":"xe cứu thương","fa":"آمبولانس","examples":[{"de":"Nach dem Unfall kam der Krankenwagen sehr schnell.","en":"After the accident the ambulance came very quickly.","ru":"После аварии скорая приехала очень быстро.","vi":"Sau khi tai nạn xảy ra, xe cứu thương đã đến rất nhanh.","fa":"بعد از تصادف آمبولانس خیلی سریع آمد."},{"de":"Bitte rufen Sie sofort einen Krankenwagen!","en":"Please call an ambulance immediately!","ru":"Пожалуйста, немедленно вызовите скорую!","vi":"Hãy gọi xe cứu thương ngay lập tức!","fa":"لطفاً فوراً با آمبولانس تماس بگیرید!"},{"de":"Der Krankenwagen brachte den Verletzten ins nächste Krankenhaus.","en":"The ambulance took the injured man to the nearest hospital.","ru":"Скорая отвезла пострадавшего в ближайшую больницу.","vi":"Xe cứu thương đã đưa người đàn ông bị thương đến bệnh viện gần nhất.","fa":"آمبولانس مرد مجروح را به نزدیکترین بیمارستان منتقل کرد."}]},{"word":"die Krankheit","en":"illness; disease","ru":"болезнь","vi":"căn bệnh","fa":"بیماری","examples":[{"de":"Diese Krankheit ist zum Glück nicht ansteckend.","en":"Fortunately, this illness is not contagious.","ru":"К счастью, эта болезнь не заразна.","vi":"May mắn thay, căn bệnh này không lây nhiễm.","fa":"خوشبختانه این بیماری مسری نیست."},{"de":"Er musste seine Reise wegen einer Krankheit absagen.","en":"He had to cancel his trip because of an illness.","ru":"Ему пришлось отменить поездку из-за болезни.","vi":"Anh ấy phải hủy chuyến đi vì bệnh.","fa":"او مجبور شد سفر خود را به دلیل بیماری لغو کند."}]},{"word":"der Krater","en":"crater","ru":"кратер","vi":"miệng núi lửa","fa":"the crater","examples":[{"de":"Auf dem Mond gibt es unzählige große Krater.","en":"On the Moon there are countless large craters.","ru":"На Луне бесчисленное множество больших кратеров.","vi":"Có vô số miệng hố lớn trên mặt trăng.","fa":"دهانه های بزرگ بی شماری روی ماه وجود دارد."},{"de":"Der Krater entstand durch den Einschlag eines Meteoriten.","en":"The crater was formed by the impact of a meteorite.","ru":"Кратер образовался от удара метеорита.","vi":"Miệng núi lửa được tạo ra do tác động của thiên thạch.","fa":"این دهانه در اثر برخورد یک شهاب سنگ ایجاد شده است."},{"de":"Durch das Teleskop konnten wir die Krater deutlich erkennen.","en":"Through the telescope we could clearly make out the craters.","ru":"Через телескоп мы отчётливо различили кратеры.","vi":"Qua kính thiên văn chúng ta có thể nhìn thấy rõ các miệng hố.","fa":"از طریق تلسکوپ می توانستیم دهانه ها را به وضوح ببینیم."}]},{"word":"der Kräutertee","en":"herbal tea","ru":"травяной чай","vi":"trà thảo mộc","fa":"چای گیاهی","examples":[{"de":"Vor dem Schlafengehen trinke ich einen Kräutertee.","en":"Before going to bed I drink a herbal tea.","ru":"Перед сном я пью травяной чай.","vi":"Trước khi đi ngủ tôi uống trà thảo dược.","fa":"قبل از رفتن به رختخواب چای گیاهی می نوشم."},{"de":"Dieser Kräutertee enthält Kamille und Fenchel.","en":"This herbal tea contains chamomile and fennel.","ru":"Этот травяной чай содержит ромашку и фенхель.","vi":"Trà thảo dược này có chứa hoa cúc và thì là.","fa":"این دمنوش گیاهی حاوی بابونه و رازیانه است."},{"de":"Kräutertee hat im Gegensatz zu Kaffee kein Koffein.","en":"Unlike coffee, herbal tea has no caffeine.","ru":"В отличие от кофе, в травяном чае нет кофеина.","vi":"Không giống như cà phê, trà thảo dược không có caffeine.","fa":"برخلاف قهوه، چای گیاهی فاقد کافئین است."}]},{"word":"kreativ","en":"creative","ru":"творческий, креативный","vi":"sáng tạo","fa":"خلاق","examples":[{"de":"Bei dieser Aufgabe kannst du kreativ sein.","en":"You can be creative with this task.","ru":"В этом задании ты можешь проявить креативность.","vi":"Bạn có thể sáng tạo với nhiệm vụ này.","fa":"شما می توانید با این کار خلاق باشید."},{"de":"Sie hat viele kreative Ideen für das Projekt.","en":"She has many creative ideas for the project.","ru":"У неё много креативных идей для проекта.","vi":"Cô ấy có nhiều ý tưởng sáng tạo cho dự án.","fa":"او ایده های خلاقانه زیادی برای این پروژه دارد."}]},{"word":"der Kredit","en":"loan, credit","ru":"кредит","vi":"tín dụng","fa":"اعتبار","examples":[{"de":"Sie hat einen Kredit für das neue Auto aufgenommen.","en":"She took out a loan for the new car.","ru":"Она взяла кредит на новую машину.","vi":"Cô ấy đã vay một khoản tiền để mua chiếc xe mới.","fa":"او برای ماشین جدید وام گرفت."},{"de":"Die Bank hat ihm den Kredit genehmigt.","en":"The bank approved his loan.","ru":"Банк одобрил ему кредит.","vi":"Ngân hàng đã chấp thuận khoản vay cho anh ta.","fa":"بانک این وام را برای او تایید کرد."}]},{"word":"der Kreis","en":"circle","ru":"круг","vi":"the circle","fa":"دایره","examples":[{"de":"Die Kinder stehen im Kreis.","en":"The children are standing in a circle.","ru":"Дети стоят в кругу.","vi":"Trẻ đứng thành vòng tròn.","fa":"بچه ها در یک دایره ایستاده اند."},{"de":"Er malte einen großen Kreis auf das Papier.","en":"He drew a large circle on the paper.","ru":"Он нарисовал большой круг на бумаге.","vi":"Anh vẽ một vòng tròn lớn lên giấy.","fa":"دایره بزرگی روی کاغذ کشید."}]},{"word":"die Kreislaufwirtschaft","en":"circular economy","ru":"циркулярная экономика, экономика замкнутого цикла","vi":"nền kinh tế tuần hoàn","fa":"اقتصاد دایره ای","examples":[{"de":"In einer Kreislaufwirtschaft wird fast nichts weggeworfen.","en":"In a circular economy almost nothing is thrown away.","ru":"В циркулярной экономике почти ничего не выбрасывают.","vi":"Trong nền kinh tế tuần hoàn, hầu như không có gì bị vứt đi.","fa":"در اقتصاد دایره ای، تقریبا هیچ چیز دور ریخته نمی شود."},{"de":"Die Kreislaufwirtschaft soll Rohstoffe wieder nutzbar machen.","en":"The circular economy is meant to make raw materials reusable.","ru":"Циркулярная экономика должна сделать сырьё пригодным для повторного использования.","vi":"Nền kinh tế tuần hoàn nhằm mục đích làm cho nguyên liệu thô có thể sử dụng được trở lại.","fa":"اقتصاد دایره ای برای قابل استفاده مجدد مواد خام در نظر گرفته شده است."},{"de":"Viele Firmen setzen heute auf eine Kreislaufwirtschaft.","en":"Many companies now rely on a circular economy.","ru":"Многие фирмы сегодня делают ставку на циркулярную экономику.","vi":"Nhiều công ty ngày nay đang dựa vào nền kinh tế tuần hoàn.","fa":"امروزه بسیاری از شرکت ها به اقتصاد دایره ای متکی هستند."}]},{"word":"das Kreuz","en":"cross","ru":"крест","vi":"cây thánh giá","fa":"صلیب","examples":[{"de":"Über dem Altar hängt ein großes Kreuz.","en":"A large cross hangs above the altar.","ru":"Над алтарём висит большой крест.","vi":"Một cây thánh giá lớn treo phía trên bàn thờ.","fa":"صلیب بزرگی بالای محراب آویزان است."},{"de":"Setzen Sie ein Kreuz bei der richtigen Antwort.","en":"Put a cross next to the correct answer.","ru":"Поставьте крестик рядом с правильным ответом.","vi":"Hãy gạch chéo trước câu trả lời đúng.","fa":"در کنار پاسخ صحیح یک ضربدر قرار دهید."}]},{"word":"die Kreuzung","en":"crossroads, junction","ru":"перекрёсток","vi":"ngã tư","fa":"تقاطع","examples":[{"de":"An der nächsten Kreuzung biegen wir links ab.","en":"At the next junction we turn left.","ru":"На следующем перекрёстке мы повернём налево.","vi":"Ở ngã tư tiếp theo, chúng tôi rẽ trái.","fa":"در تقاطع بعدی به چپ میپیچیم."},{"de":"Die Kreuzung ist sehr gefährlich.","en":"The crossroads is very dangerous.","ru":"Этот перекрёсток очень опасный.","vi":"Giao lộ rất nguy hiểm.","fa":"تقاطع بسیار خطرناک است."},{"de":"Halte bitte vor der Kreuzung an.","en":"Please stop before the junction.","ru":"Остановись, пожалуйста, перед перекрёстком.","vi":"Hãy dừng lại trước ngã tư.","fa":"لطفا قبل از تقاطع توقف کنید."}]},{"word":"der Krieg","en":"war","ru":"война","vi":"cuộc chiến","fa":"جنگ","examples":[{"de":"Der Krieg dauerte mehrere Jahre.","en":"The war lasted several years.","ru":"Война длилась несколько лет.","vi":"Cuộc chiến kéo dài vài năm.","fa":"جنگ چندین سال طول کشید."},{"de":"Viele Menschen mussten wegen des Krieges fliehen.","en":"Many people had to flee because of the war.","ru":"Многим людям пришлось бежать из-за войны.","vi":"Nhiều người phải chạy trốn vì chiến tranh.","fa":"بسیاری از مردم به دلیل جنگ مجبور به فرار شدند."}]},{"word":"kriegen","en":"to get, receive (colloquial)","ru":"получать","vi":"nhận được","fa":"دریافت کنید","examples":[{"de":"Ich habe zum Geburtstag ein Fahrrad gekriegt.","en":"I got a bike for my birthday.","ru":"На день рождения я получил велосипед.","vi":"Tôi có một chiếc xe đạp vào ngày sinh nhật của tôi.","fa":"برای تولدم دوچرخه گرفتم."},{"de":"Kriegst du morgen frei?","en":"Are you getting a day off tomorrow?","ru":"Ты получишь завтра выходной?","vi":"Ngày mai bạn có rảnh không?","fa":"فردا آزاد هستی؟"}]},{"word":"der Krimi","en":"crime novel, thriller","ru":"детектив (фильм/книга)","vi":"the crime thriller","fa":"تریلر جنایی","examples":[{"de":"Ich lese gerade einen spannenden Krimi.","en":"I'm currently reading an exciting crime novel.","ru":"Я сейчас читаю захватывающий детектив.","vi":"Tôi hiện đang đọc một cuốn tiểu thuyết tội phạm thú vị.","fa":"در حال حاضر مشغول خواندن یک رمان جنایی هیجان انگیز هستم."},{"de":"Im Fernsehen läuft heute ein neuer Krimi.","en":"A new crime show is on TV tonight.","ru":"Сегодня по телевизору идёт новый детектив.","vi":"Có một bộ phim tội phạm mới trên TV ngày hôm nay.","fa":"امروز یک درام جنایی جدید در تلویزیون پخش می شود."}]},{"word":"die Kriminalpolizei","en":"criminal investigation department","ru":"уголовный розыск","vi":"cảnh sát hình sự","fa":"پلیس جنایی","examples":[{"de":"Die Kriminalpolizei ermittelt in dem Mordfall.","en":"The criminal investigation department is investigating the murder case.","ru":"Уголовный розыск расследует дело об убийстве.","vi":"Cảnh sát hình sự đang điều tra vụ án giết người.","fa":"پلیس جنایی در حال بررسی پرونده قتل است."},{"de":"Er arbeitet seit zehn Jahren bei der Kriminalpolizei.","en":"He has worked for the criminal investigation department for ten years.","ru":"Он работает в уголовном розыске уже десять лет.","vi":"Anh ta đã làm việc cho cục điều tra tội phạm được mười năm.","fa":"او ده سال است که در اداره تحقیقات جنایی کار می کند."}]},{"word":"kriminell","en":"criminal","ru":"криминальный, преступный","vi":"tội phạm","fa":"جنایتکار","examples":[{"de":"Er wurde in eine kriminelle Bande verwickelt.","en":"He got involved with a criminal gang.","ru":"Он оказался втянут в преступную банду.","vi":"Anh ta vướng vào một băng nhóm tội phạm.","fa":"او درگیر یک باند جنایتکار شد."},{"de":"Solches Verhalten ist eindeutig kriminell.","en":"Such behavior is clearly criminal.","ru":"Такое поведение однозначно является преступным.","vi":"Hành vi như vậy rõ ràng là tội phạm.","fa":"چنین رفتاری آشکارا مجرمانه است."}]},{"word":"die Krise","en":"crisis","ru":"кризис","vi":"cuộc khủng hoảng","fa":"بحران","examples":[{"de":"Das Land steckt in einer schweren Krise.","en":"The country is in a severe crisis.","ru":"Страна переживает тяжёлый кризис.","vi":"Đất nước đang trong tình trạng khủng hoảng nghiêm trọng.","fa":"کشور در یک بحران جدی قرار دارد."},{"de":"Die Firma hat die Krise erfolgreich überstanden.","en":"The company successfully survived the crisis.","ru":"Компания успешно пережила кризис.","vi":"Công ty đã vượt qua khủng hoảng thành công.","fa":"این شرکت با موفقیت از بحران عبور کرد."}]},{"word":"die Kritik","en":"criticism; review","ru":"критика; рецензия","vi":"sự chỉ trích","fa":"انتقاد","examples":[{"de":"Er kann mit Kritik an seiner Arbeit nur schwer umgehen.","en":"He finds it difficult to deal with criticism of his work.","ru":"Ему трудно воспринимать критику своей работы.","vi":"Anh ấy cảm thấy khó khăn khi phải đối mặt với những lời chỉ trích về công việc của mình.","fa":"او به سختی می تواند با انتقاداتی که از کارش می شود کنار بیاید."},{"de":"Die Kritik des Films in der Zeitung war sehr positiv.","en":"The film review in the newspaper was very positive.","ru":"Рецензия на фильм в газете была очень положительной.","vi":"Đánh giá về bộ phim trên báo rất tích cực.","fa":"نقد فیلم در روزنامه بسیار مثبت بود."},{"de":"Konstruktive Kritik hilft uns, besser zu werden.","en":"Constructive criticism helps us to get better.","ru":"Конструктивная критика помогает нам становиться лучше.","vi":"Những lời phê bình mang tính xây dựng giúp chúng ta trở nên tốt hơn.","fa":"انتقاد سازنده به ما کمک می کند تا بهتر شویم."}]},{"word":"kritisch","en":"critical","ru":"критический, критичный","vi":"quan trọng","fa":"انتقادی","examples":[{"de":"Er stellt immer kritische Fragen.","en":"He always asks critical questions.","ru":"Он всегда задаёт критические вопросы.","vi":"Anh ấy luôn đặt những câu hỏi mang tính phê phán.","fa":"او همیشه سوالات انتقادی می پرسد."},{"de":"Die Lage im Land ist sehr kritisch.","en":"The situation in the country is very critical.","ru":"Ситуация в стране очень критическая.","vi":"Tình hình trong nước rất nguy kịch.","fa":"وضعیت کشور بسیار بحرانی است."},{"de":"Man sollte Nachrichten kritisch lesen.","en":"One should read the news critically.","ru":"Новости следует читать критически.","vi":"Bạn nên đọc tin tức một cách nghiêm túc.","fa":"شما باید اخبار را انتقادی بخوانید."}]},{"word":"kritisieren","en":"to criticize","ru":"критиковать","vi":"chỉ trích","fa":"انتقاد کنید","examples":[{"de":"Der Chef kritisierte die schlechte Arbeit.","en":"The boss criticized the poor work.","ru":"Начальник раскритиковал плохую работу.","vi":"Ông chủ chỉ trích công việc kém.","fa":"رئیس از کار ضعیف انتقاد کرد."},{"de":"Man sollte nicht immer nur kritisieren.","en":"One shouldn't always just criticize.","ru":"Не стоит всегда только критиковать.","vi":"Bạn không nên lúc nào cũng chỉ trích.","fa":"همیشه نباید فقط انتقاد کرد."}]},{"word":"die Küche","en":"kitchen","ru":"кухня","vi":"nhà bếp","fa":"آشپزخانه","examples":[{"de":"Sie kocht gerade in der Küche.","en":"She is cooking in the kitchen right now.","ru":"Она сейчас готовит на кухне.","vi":"Hiện tại cô đang nấu ăn trong bếp.","fa":"او در حال حاضر در آشپزخانه مشغول آشپزی است."},{"de":"Unsere neue Küche ist sehr modern.","en":"Our new kitchen is very modern.","ru":"Наша новая кухня очень современная.","vi":"Nhà bếp mới của chúng tôi rất hiện đại.","fa":"آشپزخانه جدید ما بسیار مدرن است."}]},{"word":"der Kuchen","en":"cake","ru":"пирог, торт","vi":"cái bánh","fa":"کیک","examples":[{"de":"Meine Oma backt jeden Sonntag einen Kuchen.","en":"My grandma bakes a cake every Sunday.","ru":"Моя бабушка печёт пирог каждое воскресенье.","vi":"Bà tôi nướng bánh vào mỗi Chủ Nhật.","fa":"مادربزرگ من هر یکشنبه یک کیک می پزد."},{"de":"Der Kuchen schmeckt nach Schokolade.","en":"The cake tastes like chocolate.","ru":"Торт на вкус шоколадный.","vi":"Bánh có vị như sôcôla.","fa":"طعم کیک شبیه شکلات است."}]},{"word":"der Kugelschreiber","en":"ballpoint pen","ru":"шариковая ручка","vi":"bút bi","fa":"قلم توپ","examples":[{"de":"Hast du einen Kugelschreiber für mich?","en":"Do you have a pen for me?","ru":"У тебя есть для меня шариковая ручка?","vi":"Bạn có bút cho tôi không?","fa":"آیا برای من قلم داری؟"},{"de":"Der Kugelschreiber schreibt nicht mehr.","en":"The pen doesn't write anymore.","ru":"Ручка больше не пишет.","vi":"Cây bút bi không còn viết được nữa.","fa":"خودکار دیگر نمی نویسد."}]},{"word":"kühl","en":"cool","ru":"прохладный","vi":"mát mẻ","fa":"باحال","examples":[{"de":"Abends wird es hier ziemlich kühl.","en":"It gets quite cool here in the evenings.","ru":"По вечерам здесь становится довольно прохладно.","vi":"Buổi tối ở đây khá mát mẻ.","fa":"عصرها اینجا خیلی خنک می شود."},{"de":"Bewahren Sie den Saft kühl auf.","en":"Keep the juice cool.","ru":"Храните сок в прохладном месте.","vi":"Giữ nước ép mát.","fa":"آب میوه را خنک نگه دارید."}]},{"word":"die Kühlschranktür","en":"fridge door","ru":"дверца холодильника","vi":"cửa tủ lạnh","fa":"درب یخچال","examples":[{"de":"Bitte mach die Kühlschranktür richtig zu.","en":"Please close the fridge door properly.","ru":"Пожалуйста, закрой дверцу холодильника как следует.","vi":"Hãy đóng cửa tủ lạnh đúng cách.","fa":"لطفا درب یخچال را به درستی ببندید."},{"de":"An der Kühlschranktür hängen viele bunte Zettel.","en":"Many colourful notes hang on the fridge door.","ru":"На дверце холодильника висит много цветных записок.","vi":"Có rất nhiều mảnh giấy nhiều màu sắc được treo trên cửa tủ lạnh.","fa":"تعداد زیادی کاغذ رنگارنگ روی درب یخچال آویزان شده است."},{"de":"Die Kühlschranktür ging nicht mehr ganz zu.","en":"The fridge door would no longer close completely.","ru":"Дверца холодильника больше не закрывалась до конца.","vi":"Cửa tủ lạnh không còn đóng hoàn toàn nữa.","fa":"درب یخچال دیگر به طور کامل بسته نمی شود."}]},{"word":"der Kuli","en":"biro; ballpoint pen","ru":"шариковая ручка","vi":"cu li","fa":"باحال","examples":[{"de":"Kannst du mir bitte deinen Kuli leihen?","en":"Could you please lend me your biro?","ru":"Не мог бы ты одолжить мне свою шариковую ручку?","vi":"Bạn có thể vui lòng cho tôi mượn cây bút của bạn được không?","fa":"میشه لطفا قلمتو به من قرض بدی؟"},{"de":"Mein Kuli schreibt leider nicht mehr.","en":"Unfortunately my biro no longer writes.","ru":"Моя шариковая ручка, к сожалению, больше не пишет.","vi":"Rất tiếc là bút của tôi không viết được nữa.","fa":"متأسفانه قلم من دیگر نمی نویسد."},{"de":"Auf dem Schreibtisch liegen mehrere Kulis und ein Bleistift.","en":"On the desk there are several biros and a pencil.","ru":"На письменном столе лежат несколько ручек и карандаш.","vi":"Có một số cây bút và bút chì trên bàn.","fa":"چند خودکار و یک مداد روی میز وجود دارد."}]},{"word":"die Kultur","en":"culture","ru":"культура","vi":"văn hóa","fa":"فرهنگ","examples":[{"de":"Er interessiert sich sehr für fremde Kulturen.","en":"He is very interested in foreign cultures.","ru":"Он очень интересуется чужими культурами.","vi":"Anh ấy rất quan tâm đến văn hóa nước ngoài.","fa":"او علاقه زیادی به فرهنگ های خارجی دارد."},{"de":"Musik und Kunst gehören zur Kultur eines Landes.","en":"Music and art are part of a country's culture.","ru":"Музыка и искусство — часть культуры страны.","vi":"Âm nhạc và nghệ thuật là một phần của nền văn hóa của một quốc gia.","fa":"موسیقی و هنر بخشی از فرهنگ یک کشور است."}]},{"word":"der Kunde","en":"customer","ru":"клиент","vi":"khách hàng","fa":"مشتری","examples":[{"de":"Der Kunde ist mit dem Service zufrieden.","en":"The customer is satisfied with the service.","ru":"Клиент доволен обслуживанием.","vi":"Khách hàng hài lòng với dịch vụ.","fa":"مشتری از خدمات راضی است."},{"de":"Wir haben viele treue Kunden.","en":"We have many loyal customers.","ru":"У нас много постоянных клиентов.","vi":"Chúng tôi có nhiều khách hàng trung thành.","fa":"ما مشتریان وفادار زیادی داریم."}]},{"word":"das Kundenkonto","en":"customer account","ru":"личный кабинет клиента (учётная запись)","vi":"tài khoản khách hàng","fa":"حساب مشتری","examples":[{"de":"Bitte melden Sie sich mit Ihrem Kundenkonto an.","en":"Please log in with your customer account.","ru":"Пожалуйста, войдите под своей учётной записью клиента.","vi":"Vui lòng đăng nhập bằng tài khoản khách hàng của bạn.","fa":"لطفا با حساب مشتری خود وارد شوید."},{"de":"In Ihrem Kundenkonto können Sie alle Bestellungen sehen.","en":"In your customer account you can see all your orders.","ru":"В личном кабинете вы можете видеть все свои заказы.","vi":"Bạn có thể xem tất cả các đơn đặt hàng trong tài khoản khách hàng của bạn.","fa":"شما می توانید تمام سفارشات را در حساب مشتری خود مشاهده کنید."},{"de":"Ich habe mein Passwort für das Kundenkonto vergessen.","en":"I have forgotten my password for the customer account.","ru":"Я забыл пароль от личного кабинета.","vi":"Tôi quên mật khẩu tài khoản khách hàng.","fa":"رمز عبور حساب کاربری خود را فراموش کرده ام."}]},{"word":"kündigen","en":"to quit, give notice, terminate","ru":"увольняться, расторгать (договор)","vi":"hủy bỏ","fa":"لغو","examples":[{"de":"Er hat seinen Job gekündigt.","en":"He quit his job.","ru":"Он уволился с работы.","vi":"Anh ấy đã nghỉ việc.","fa":"کارش را رها کرد."},{"de":"Die Firma musste ihm kündigen.","en":"The company had to lay him off.","ru":"Компании пришлось его уволить.","vi":"Công ty đã phải sa thải anh ta.","fa":"شرکت مجبور شد او را اخراج کند."}]},{"word":"die Kunst","en":"art","ru":"искусство","vi":"nghệ thuật","fa":"هنر","examples":[{"de":"Sie interessiert sich sehr für moderne Kunst.","en":"She is very interested in modern art.","ru":"Она очень интересуется современным искусством.","vi":"Cô ấy rất quan tâm đến nghệ thuật hiện đại.","fa":"او علاقه زیادی به هنر مدرن دارد."},{"de":"Im Museum kann man alte Kunst bewundern.","en":"You can admire old art in the museum.","ru":"В музее можно полюбоваться старинным искусством.","vi":"Bạn có thể chiêm ngưỡng nghệ thuật cũ trong bảo tàng.","fa":"در موزه می توانید هنرهای قدیمی را تحسین کنید."}]},{"word":"der Künstler","en":"artist","ru":"художник; артист (м.)","vi":"nghệ sĩ","fa":"هنرمند","examples":[{"de":"Der Künstler stellt seine Bilder in der Galerie aus.","en":"The artist is exhibiting his paintings in the gallery.","ru":"Художник выставляет свои картины в галерее.","vi":"Nghệ sĩ trưng bày những bức tranh của mình trong phòng trưng bày.","fa":"این هنرمند تصاویر خود را در گالری به نمایش می گذارد."},{"de":"Viele Künstler leben von ihren Werken kaum.","en":"Many artists can barely live off their works.","ru":"Многие художники едва живут на доходы от своих работ.","vi":"Nhiều nghệ sĩ hầu như không kiếm sống được từ công việc của mình.","fa":"بسیاری از هنرمندان به سختی از کار خود امرار معاش می کنند."},{"de":"Der bekannte Künstler gab gestern ein Konzert.","en":"The famous artist gave a concert yesterday.","ru":"Известный артист вчера дал концерт.","vi":"Nghệ sĩ nổi tiếng đã tổ chức một buổi hòa nhạc ngày hôm qua.","fa":"این هنرمند سرشناس دیروز کنسرتی برگزار کرد."}]},{"word":"die Künstlerin","en":"artist (female)","ru":"художница; артистка (ж.)","vi":"nghệ sĩ","fa":"هنرمند","examples":[{"de":"Die Künstlerin hat ein neues Atelier gemietet.","en":"The artist has rented a new studio.","ru":"Художница арендовала новую мастерскую.","vi":"Nghệ sĩ đã thuê một studio mới.","fa":"این هنرمند یک استودیوی جدید اجاره کرده است."},{"de":"Diese Künstlerin ist für ihre Skulpturen berühmt.","en":"This artist is famous for her sculptures.","ru":"Эта художница знаменита своими скульптурами.","vi":"Nghệ sĩ này nổi tiếng với tác phẩm điêu khắc của mình.","fa":"این هنرمند به خاطر مجسمه هایش مشهور است."},{"de":"Die junge Künstlerin gewann einen wichtigen Preis.","en":"The young artist won an important prize.","ru":"Молодая художница выиграла важную премию.","vi":"Nghệ sĩ trẻ đã giành được giải thưởng quan trọng.","fa":"این هنرمند جوان برنده جایزه مهمی شد."}]},{"word":"künstlich","en":"artificial","ru":"искусственный","vi":"nhân tạo","fa":"مصنوعی","examples":[{"de":"Das Getränk enthält künstliche Aromen.","en":"The drink contains artificial flavors.","ru":"Напиток содержит искусственные ароматизаторы.","vi":"Đồ uống có chứa hương vị nhân tạo.","fa":"این نوشیدنی حاوی طعم دهنده های مصنوعی است."},{"de":"Der Baum im Büro ist künstlich.","en":"The tree in the office is artificial.","ru":"Дерево в офисе искусственное.","vi":"Cây trong văn phòng là cây nhân tạo.","fa":"درخت در دفتر مصنوعی است."}]},{"word":"die künstliche Intelligenz","en":"artificial intelligence","ru":"искусственный интеллект","vi":"trí tuệ nhân tạo","fa":"هوش مصنوعی","examples":[{"de":"Künstliche Intelligenz wird heute in fast jeder Branche eingesetzt.","en":"Artificial intelligence is now used in almost every industry.","ru":"Искусственный интеллект сегодня применяется почти в каждой отрасли.","vi":"Trí tuệ nhân tạo được sử dụng trong hầu hết mọi ngành công nghiệp ngày nay.","fa":"هوش مصنوعی امروزه تقریباً در هر صنعتی مورد استفاده قرار می گیرد."},{"de":"Viele Menschen haben Angst vor künstlicher Intelligenz.","en":"Many people are afraid of artificial intelligence.","ru":"Многие люди боятся искусственного интеллекта.","vi":"Nhiều người sợ trí tuệ nhân tạo.","fa":"بسیاری از افراد از هوش مصنوعی می ترسند."},{"de":"Künstliche Intelligenz kann Ärzten bei der Diagnose helfen.","en":"Artificial intelligence can help doctors with diagnosis.","ru":"Искусственный интеллект может помогать врачам в постановке диагноза.","vi":"Trí tuệ nhân tạo có thể giúp bác sĩ chẩn đoán.","fa":"Artificial intelligence can help doctors diagnose."}]},{"word":"der Kunststoff","en":"plastic","ru":"пластмасса, пластик","vi":"nhựa","fa":"پلاستیک","examples":[{"de":"Die Flasche ist aus Kunststoff und lässt sich recyceln.","en":"The bottle is made of plastic and can be recycled.","ru":"Бутылка сделана из пластика и подлежит переработке.","vi":"Chai được làm bằng nhựa và có thể tái chế.","fa":"این بطری از پلاستیک ساخته شده و قابل بازیافت است."},{"de":"Viele Spielzeuge bestehen heute aus billigem Kunststoff.","en":"Many toys today are made of cheap plastic.","ru":"Многие игрушки сегодня делают из дешёвой пластмассы.","vi":"Nhiều đồ chơi ngày nay được làm bằng nhựa rẻ tiền.","fa":"امروزه بسیاری از اسباب بازی ها از پلاستیک ارزان قیمت ساخته می شوند."},{"de":"Kunststoff ist leicht, aber nicht immer umweltfreundlich.","en":"Plastic is light, but not always environmentally friendly.","ru":"Пластик лёгкий, но не всегда экологичный.","vi":"Nhựa nhẹ nhưng không phải lúc nào cũng thân thiện với môi trường.","fa":"پلاستیک سبک است، اما همیشه دوستدار محیط زیست نیست."}]},{"word":"der Kurs","en":"course (class); exchange rate","ru":"курс (занятия); валютный курс","vi":"khóa học","fa":"دوره","examples":[{"de":"Sie besucht einen Kurs für Deutsch als Fremdsprache.","en":"She is attending a German-as-a-foreign-language course.","ru":"Она посещает курс немецкого как иностранного.","vi":"Cô ấy đang tham gia một khóa học tiếng Đức như một ngoại ngữ.","fa":"او در دوره ای برای آلمانی به عنوان زبان خارجی شرکت می کند."},{"de":"Der Kurs des Euro ist heute gestiegen.","en":"The euro exchange rate rose today.","ru":"Курс евро сегодня вырос.","vi":"Tỷ giá đồng euro hôm nay tăng.","fa":"نرخ یورو امروز افزایش یافت."}]},{"word":"der Kursleiter","en":"course instructor; course leader (male)","ru":"преподаватель курса, руководитель курса (м.)","vi":"người lãnh đạo khóa học","fa":"رهبر دوره","examples":[{"de":"Unser Kursleiter erklärt die Grammatik immer sehr verständlich.","en":"Our course instructor always explains the grammar very clearly.","ru":"Наш преподаватель курса всегда очень понятно объясняет грамматику.","vi":"Người hướng dẫn của chúng tôi luôn giải thích ngữ pháp rất rõ ràng.","fa":"مربی ما همیشه گرامر را خیلی واضح توضیح می دهد."},{"de":"Der Kursleiter hat die Prüfung für nächste Woche angekündigt.","en":"The course leader has announced the exam for next week.","ru":"Руководитель курса объявил экзамен на следующую неделю.","vi":"Giảng viên khóa học đã thông báo bài kiểm tra cho tuần tới.","fa":"مدرس دوره آزمون هفته آینده را اعلام کرده است."},{"de":"Bei Fragen kannst du dich jederzeit an den Kursleiter wenden.","en":"If you have questions, you can turn to the course instructor at any time.","ru":"С вопросами ты в любое время можешь обратиться к преподавателю курса.","vi":"Nếu có thắc mắc, bạn có thể liên hệ với người hướng dẫn khóa học bất cứ lúc nào.","fa":"در صورت داشتن هر گونه سوال می توانید در هر زمان با مدرس دوره تماس بگیرید."}]},{"word":"die Kursleiterin","en":"course instructor; course leader (female)","ru":"преподавательница курса, руководительница курса (ж.)","vi":"người lãnh đạo khóa học","fa":"رهبر دوره","examples":[{"de":"Unsere Kursleiterin spricht drei Sprachen fließend.","en":"Our course instructor speaks three languages fluently.","ru":"Наша преподавательница курса свободно говорит на трёх языках.","vi":"Người hướng dẫn khóa học của chúng tôi nói trôi chảy ba thứ tiếng.","fa":"رهبر دوره ما به سه زبان روان صحبت می کند."},{"de":"Die Kursleiterin hat die Hausaufgaben für morgen erklärt.","en":"The course leader explained the homework for tomorrow.","ru":"Преподавательница курса объяснила домашнее задание на завтра.","vi":"Người hướng dẫn khóa học đã giải thích bài tập về nhà ngày mai.","fa":"مدرس دوره تکلیف فردا را توضیح داد."},{"de":"Ich habe die Kursleiterin gebeten, die Übung noch einmal zu wiederholen.","en":"I asked the course instructor to repeat the exercise once more.","ru":"Я попросил преподавательницу курса ещё раз повторить упражнение.","vi":"Tôi yêu cầu người hướng dẫn lặp lại bài tập một lần nữa.","fa":"از مربی خواستم دوباره تمرین را تکرار کند."}]},{"word":"die Kurve","en":"curve, bend","ru":"поворот, изгиб","vi":"đường cong","fa":"منحنی","examples":[{"de":"Fahren Sie in der Kurve langsamer.","en":"Drive slower on the bend.","ru":"На повороте езжайте медленнее.","vi":"Lái xe chậm hơn khi vào cua.","fa":"هنگام پیچیدن آهسته تر رانندگی کنید."},{"de":"Die Straße hat viele enge Kurven.","en":"The road has many sharp curves.","ru":"На дороге много крутых поворотов.","vi":"Con đường có nhiều khúc cua gấp.","fa":"جاده پیچ های بسیار تنگ دارد."}]},{"word":"kurz","en":"short","ru":"короткий","vi":"ngắn","fa":"کوتاه","examples":[{"de":"Sie hat sich die Haare kurz geschnitten.","en":"She cut her hair short.","ru":"Она коротко подстригла волосы.","vi":"Cô cắt tóc ngắn.","fa":"موهایش را کوتاه کرد."},{"de":"Ich mache nur eine kurze Pause.","en":"I'm just taking a short break.","ru":"Я сделаю лишь короткий перерыв.","vi":"Tôi chỉ đang nghỉ ngơi một lát thôi.","fa":"من فقط یک استراحت کوتاه می کنم."}]},{"word":"kürzlich","en":"recently","ru":"недавно","vi":"gần đây","fa":"اخیرا","examples":[{"de":"Wir haben uns erst kürzlich kennengelernt.","en":"We only met recently.","ru":"Мы познакомились совсем недавно.","vi":"Chúng tôi chỉ mới gặp nhau gần đây thôi.","fa":"ما اخیراً همدیگر را دیدیم."},{"de":"Kürzlich habe ich ein interessantes Buch gelesen.","en":"I recently read an interesting book.","ru":"Недавно я прочитал интересную книгу.","vi":"Gần đây tôi đọc được một cuốn sách thú vị.","fa":"اخیرا کتاب جالبی خواندم."}]},{"word":"das Kuscheltier","en":"cuddly toy; soft toy","ru":"мягкая игрушка","vi":"đồ chơi đáng yêu","fa":"اسباب بازی نوازش","examples":[{"de":"Das kleine Mädchen schläft jede Nacht mit ihrem Kuscheltier.","en":"The little girl sleeps with her cuddly toy every night.","ru":"Маленькая девочка каждую ночь спит со своей мягкой игрушкой.","vi":"Cô bé ngủ với con thú nhồi bông của mình mỗi đêm.","fa":"دختر بچه هر شب با حیوان عروسکی خود می خوابد."},{"de":"Zum Geburtstag bekam mein Sohn ein weiches Kuscheltier.","en":"For his birthday my son got a soft cuddly toy.","ru":"На день рождения мой сын получил мягкую игрушку.","vi":"Con trai tôi có một món đồ chơi mềm mại nhân dịp sinh nhật.","fa":"پسرم برای تولدش یک اسباب بازی نوازش نرم گرفت."},{"de":"Im Kinderzimmer liegen viele bunte Kuscheltiere.","en":"There are many colourful cuddly toys in the children's room.","ru":"В детской комнате лежит много разноцветных мягких игрушек.","vi":"Trong phòng trẻ em có rất nhiều đồ chơi âu yếm đầy màu sắc.","fa":"تعداد زیادی اسباب بازی های رنگارنگ در اتاق کودکان وجود دارد."}]},{"word":"der Kuss","en":"kiss","ru":"поцелуй","vi":"nụ hôn","fa":"بوسه","examples":[{"de":"Sie gab ihm einen Kuss auf die Wange.","en":"She gave him a kiss on the cheek.","ru":"Она поцеловала его в щёку.","vi":"Cô trao cho anh một nụ hôn lên má.","fa":"بوسه ای بر گونه اش زد."},{"de":"Zum Abschied gab es einen letzten Kuss.","en":"There was one last kiss before parting.","ru":"На прощание был последний поцелуй.","vi":"Có một nụ hôn cuối cùng để nói lời tạm biệt.","fa":"آخرین بوسه برای خداحافظی بود."}]},{"word":"küssen","en":"to kiss","ru":"целовать","vi":"hôn","fa":"بوسه","examples":[{"de":"Er küsste sie zum Abschied.","en":"He kissed her goodbye.","ru":"Он поцеловал её на прощание.","vi":"Anh hôn tạm biệt cô.","fa":"او را بوسید خداحافظی."},{"de":"Die beiden küssten sich am Bahnhof.","en":"The two of them kissed at the train station.","ru":"Они поцеловались на вокзале.","vi":"Hai người hôn nhau ở ga tàu.","fa":"آن دو در ایستگاه قطار بوسیدند."}]},{"word":"die Küste","en":"the coast","ru":"побережье","vi":"bờ biển","fa":"ساحل","examples":[{"de":"Wir haben unseren Urlaub an der Küste verbracht.","en":"We spent our vacation on the coast.","ru":"Мы провели отпуск на побережье.","vi":"Chúng tôi đã dành kỳ nghỉ của mình trên bờ biển.","fa":"تعطیلاتمان را در ساحل گذراندیم."},{"de":"Die Stadt liegt direkt an der Küste.","en":"The city is located right on the coast.","ru":"Город расположен прямо на побережье.","vi":"Thành phố nằm ngay trên bờ biển.","fa":"این شهر مستقیماً در ساحل واقع شده است."}]},{"word":"das Kuvert","en":"the envelope","ru":"конверт","vi":"phong bì","fa":"پاکت نامه","examples":[{"de":"Sie steckte den Brief in ein Kuvert.","en":"She put the letter in an envelope.","ru":"Она положила письмо в конверт.","vi":"Cô bỏ lá thư vào phong bì.","fa":"نامه را در یک پاکت گذاشت."},{"de":"Auf dem Kuvert stand keine Adresse.","en":"There was no address on the envelope.","ru":"На конверте не было адреса.","vi":"Trên phong bì không có địa chỉ.","fa":"هیچ آدرسی روی پاکت نبود."}]},{"word":"lächeln","en":"to smile","ru":"улыбаться","vi":"mỉm cười","fa":"لبخند بزن","examples":[{"de":"Das Kind lächelte glücklich.","en":"The child smiled happily.","ru":"Ребёнок счастливо улыбался.","vi":"Đứa trẻ mỉm cười hạnh phúc.","fa":"کودک با خوشحالی لبخند زد."},{"de":"Sie lächelte mir freundlich zu.","en":"She smiled at me kindly.","ru":"Она приветливо улыбнулась мне.","vi":"Cô ấy mỉm cười thân thiện với tôi.","fa":"او با مهربانی به من لبخند زد."}]},{"word":"lachen","en":"to laugh","ru":"смеяться","vi":"cười","fa":"بخند","examples":[{"de":"Wir haben den ganzen Abend gelacht.","en":"We laughed the whole evening.","ru":"Мы смеялись весь вечер.","vi":"Chúng tôi cười suốt buổi tối.","fa":"تمام غروب خندیدیم."},{"de":"Er musste über den Witz laut lachen.","en":"He had to laugh loudly at the joke.","ru":"Он громко засмеялся над шуткой.","vi":"Anh phải cười lớn trước câu nói đùa đó.","fa":"او مجبور شد به این شوخی بلند بخندد."}]},{"word":"der Laden","en":"the shop; the store","ru":"магазин","vi":"cửa hàng","fa":"فروشگاه","examples":[{"de":"Der Laden an der Ecke verkauft frisches Obst.","en":"The shop on the corner sells fresh fruit.","ru":"Магазин на углу продаёт свежие фрукты.","vi":"Cửa hàng góc bán trái cây tươi.","fa":"مغازه گوشه ای میوه تازه می فروشد."},{"de":"Der Laden öffnet um acht Uhr.","en":"The store opens at eight o'clock.","ru":"Магазин открывается в восемь часов.","vi":"Cửa hàng mở cửa lúc tám giờ.","fa":"مغازه ساعت هشت باز می شود."}]},{"word":"die Ladestation","en":"charging station","ru":"зарядная станция","vi":"trạm sạc","fa":"ایستگاه شارژ","examples":[{"de":"Vor dem Supermarkt gibt es eine neue Ladestation.","en":"There is a new charging station in front of the supermarket.","ru":"Перед супермаркетом появилась новая зарядная станция.","vi":"Có một trạm sạc mới ở phía trước siêu thị.","fa":"یک ایستگاه شارژ جدید روبروی سوپرمارکت وجود دارد."},{"de":"An dieser Ladestation kann man sein Auto kostenlos laden.","en":"At this charging station you can charge your car for free.","ru":"На этой зарядной станции можно заряжать машину бесплатно.","vi":"Bạn có thể sạc xe miễn phí tại trạm sạc này.","fa":"در این ایستگاه شارژ می توانید خودروی خود را به صورت رایگان شارژ کنید."},{"de":"Es gibt noch zu wenige Ladestationen auf dem Land.","en":"There are still too few charging stations in the countryside.","ru":"В сельской местности зарядных станций пока слишком мало.","vi":"Hiện vẫn còn quá ít trạm sạc trong nước.","fa":"هنوز ایستگاه های شارژ بسیار کمی در کشور وجود دارد."}]},{"word":"die Ladung","en":"charge","ru":"заряд (электрический)","vi":"tải","fa":"بار","examples":[{"de":"Ein Elektron trägt eine negative Ladung.","en":"An electron carries a negative charge.","ru":"Электрон несёт отрицательный заряд.","vi":"Một electron mang điện tích âm.","fa":"یک الکترون حامل بار منفی است."},{"de":"Gleiche Ladungen stoßen sich gegenseitig ab.","en":"Like charges repel each other.","ru":"Одинаковые заряды отталкиваются друг от друга.","vi":"Các điện tích giống nhau thì đẩy nhau.","fa":"مانند بارها یکدیگر را دفع می کنند."},{"de":"Beim Reiben entsteht eine elektrische Ladung.","en":"Rubbing produces an electric charge.","ru":"При трении возникает электрический заряд.","vi":"Khi cọ xát sẽ tạo ra một điện tích.","fa":"هنگام مالش، بار الکتریکی ایجاد می شود."}]},{"word":"die Lage","en":"the situation; the location","ru":"положение; ситуация","vi":"vị trí","fa":"مکان","examples":[{"de":"Die wirtschaftliche Lage hat sich verbessert.","en":"The economic situation has improved.","ru":"Экономическая ситуация улучшилась.","vi":"Tình hình kinh tế đã được cải thiện.","fa":"وضعیت اقتصادی بهتر شده است."},{"de":"Das Hotel hat eine ruhige Lage am See.","en":"The hotel has a quiet location by the lake.","ru":"Отель имеет спокойное расположение у озера.","vi":"Khách sạn có vị trí yên tĩnh bên hồ.","fa":"این هتل دارای مکانی آرام در کنار دریاچه است."}]},{"word":"das Lager","en":"the warehouse; the camp","ru":"склад; лагерь","vi":"nhà kho","fa":"انبار","examples":[{"de":"Die Ware wird im Lager aufbewahrt.","en":"The goods are stored in the warehouse.","ru":"Товар хранится на складе.","vi":"Hàng hóa được lưu trữ trong kho.","fa":"کالا در انبار نگهداری می شود."},{"de":"Die Kinder verbrachten die Ferien in einem Lager.","en":"The children spent the holidays at a camp.","ru":"Дети провели каникулы в лагере.","vi":"Những đứa trẻ đã trải qua những ngày nghỉ trong một trại.","fa":"بچه ها تعطیلات را در کمپ سپری کردند."}]},{"word":"die Lampe","en":"the lamp","ru":"лампа","vi":"cái đèn","fa":"لامپ","examples":[{"de":"Bitte schalte die Lampe an, es ist dunkel.","en":"Please turn on the lamp, it's dark.","ru":"Пожалуйста, включи лампу, темно.","vi":"Làm ơn bật đèn lên, trời tối quá.","fa":"لطفا لامپ را روشن کنید، تاریک است."},{"de":"Die Lampe auf dem Schreibtisch ist kaputt.","en":"The lamp on the desk is broken.","ru":"Лампа на письменном столе сломана.","vi":"Đèn trên bàn bị hỏng.","fa":"لامپ روی میز خراب است."}]},{"word":"Lampenfieber haben","en":"to have stage fright","ru":"волноваться перед выступлением","vi":"mắc chứng sợ sân khấu","fa":"برای داشتن ترس صحنه","examples":[{"de":"Vor dem Auftritt hatte ich starkes Lampenfieber.","en":"Before the performance I had bad stage fright.","ru":"Перед выступлением я сильно волновался.","vi":"Trước buổi biểu diễn, tôi bị chứng sợ sân khấu trầm trọng.","fa":"قبل از اجرا، ترس شدیدی از صحنه داشتم."}]},{"word":"das Land","en":"the country; the land","ru":"страна; земля","vi":"đất nước","fa":"کشور","examples":[{"de":"Sie reist gerne in fremde Länder.","en":"She likes to travel to foreign countries.","ru":"Она любит путешествовать в чужие страны.","vi":"Cô thích đi du lịch nước ngoài.","fa":"او از سفر به کشورهای خارجی لذت می برد."},{"de":"Meine Großeltern leben auf dem Land.","en":"My grandparents live in the countryside.","ru":"Мои бабушка и дедушка живут в деревне.","vi":"Ông bà tôi sống ở quê.","fa":"پدربزرگ و مادربزرگ من در کشور زندگی می کنند."}]},{"word":"landen","en":"to land","ru":"приземляться","vi":"đất đai","fa":"زمین","examples":[{"de":"Das Flugzeug landet in zehn Minuten.","en":"The plane lands in ten minutes.","ru":"Самолёт приземлится через десять минут.","vi":"Máy bay sẽ hạ cánh trong mười phút nữa.","fa":"هواپیما ده دقیقه دیگر فرود می آید."},{"de":"Wir sind sicher in Wien gelandet.","en":"We landed safely in Vienna.","ru":"Мы благополучно приземлились в Вене.","vi":"Chúng tôi hạ cánh an toàn ở Vienna.","fa":"به سلامت در وین فرود آمدیم."}]},{"word":"die Landschaft","en":"the landscape","ru":"пейзаж; ландшафт","vi":"phong cảnh","fa":"چشم انداز","examples":[{"de":"Die Landschaft in den Alpen ist wunderschön.","en":"The landscape in the Alps is beautiful.","ru":"Пейзаж в Альпах прекрасен.","vi":"Phong cảnh ở dãy Alps rất đẹp.","fa":"چشم انداز کوه های آلپ زیباست."},{"de":"Wir haben die Landschaft vom Zug aus fotografiert.","en":"We photographed the landscape from the train.","ru":"Мы фотографировали пейзаж из поезда.","vi":"Chúng tôi chụp ảnh phong cảnh từ tàu.","fa":"ما از قطار از منظره عکس گرفتیم."}]},{"word":"die Landung","en":"landing","ru":"посадка, приземление","vi":"sự hạ cánh","fa":"فرود","examples":[{"de":"Die Landung des Flugzeugs verlief problemlos.","en":"The aircraft's landing went smoothly.","ru":"Посадка самолёта прошла гладко.","vi":"Việc hạ cánh của máy bay diễn ra suôn sẻ.","fa":"فرود هواپیما به آرامی انجام شد."},{"de":"Wegen des Nebels musste die Landung verschoben werden.","en":"Because of the fog the landing had to be postponed.","ru":"Из-за тумана посадку пришлось отложить.","vi":"Cuộc hạ cánh phải hoãn lại vì sương mù.","fa":"فرود به دلیل مه به تعویق افتاد."},{"de":"Bitte schnallen Sie sich für die Landung an.","en":"Please fasten your seatbelts for the landing.","ru":"Пожалуйста, пристегните ремни для посадки.","vi":"Vui lòng thắt dây an toàn để hạ cánh.","fa":"لطفا کمربندهای ایمنی خود را برای فرود ببندید."}]},{"word":"die Landwirtschaft","en":"agriculture; farming","ru":"сельское хозяйство","vi":"nông nghiệp","fa":"کشاورزی","examples":[{"de":"In dieser Region spielt die Landwirtschaft eine große Rolle.","en":"In this region agriculture plays a major role.","ru":"В этом регионе сельское хозяйство играет большую роль.","vi":"Nông nghiệp đóng một vai trò quan trọng trong khu vực này.","fa":"کشاورزی در این منطقه نقش عمده ای دارد."},{"de":"Die Landwirtschaft leidet unter dem trockenen Sommer.","en":"Agriculture is suffering from the dry summer.","ru":"Сельское хозяйство страдает от засушливого лета.","vi":"Nông nghiệp đang khốn khổ vì mùa hè khô hạn.","fa":"کشاورزی از تابستان خشک رنج می برد."},{"de":"Viele Menschen arbeiten hier in der Landwirtschaft.","en":"Many people here work in agriculture.","ru":"Многие люди здесь работают в сельском хозяйстве.","vi":"Nhiều người làm nông nghiệp ở đây.","fa":"بسیاری از مردم در اینجا در کشاورزی کار می کنند."}]},{"word":"lang","en":"long","ru":"длинный","vi":"dài","fa":"طولانی","examples":[{"de":"Sie hat lange, dunkle Haare.","en":"She has long, dark hair.","ru":"У неё длинные тёмные волосы.","vi":"Cô ấy có mái tóc dài và đen.","fa":"او موهای بلند و تیره ای دارد."},{"de":"Der Weg zur Arbeit ist sehr lang.","en":"The way to work is very long.","ru":"Дорога на работу очень длинная.","vi":"Con đường đi làm còn rất dài.","fa":"راه کار بسیار طولانی است."}]},{"word":"lange","en":"for a long time; long","ru":"долго","vi":"dài","fa":"طولانی","examples":[{"de":"Wir haben lange auf den Bus gewartet.","en":"We waited for the bus for a long time.","ru":"Мы долго ждали автобус.","vi":"Chúng tôi đã đợi xe buýt rất lâu.","fa":"مدت زیادی منتظر اتوبوس بودیم."},{"de":"Wie lange dauert der Film?","en":"How long does the movie last?","ru":"Сколько времени длится фильм?","vi":"Phim dài bao nhiêu?","fa":"مدت زمان فیلم چقدر است؟"}]},{"word":"die Länge","en":"length","ru":"длина","vi":"chiều dài","fa":"طول","examples":[{"de":"Die Länge des Tisches beträgt zwei Meter.","en":"The length of the table is two metres.","ru":"Длина стола — два метра.","vi":"Chiều dài của bàn là hai mét.","fa":"طول میز دو متر است."},{"de":"Welche Länge soll der Rock haben?","en":"What length should the skirt be?","ru":"Какой длины должна быть юбка?","vi":"Váy nên dài bao nhiêu?","fa":"قد دامن چقدر باید باشد؟"},{"de":"Wir messen jetzt die Länge und die Breite des Raumes.","en":"We now measure the length and the width of the room.","ru":"Теперь мы измеряем длину и ширину комнаты.","vi":"Bây giờ chúng tôi đo chiều dài và chiều rộng của căn phòng.","fa":"اکنون طول و عرض اتاق را اندازه می گیریم."}]},{"word":"die Langeweile","en":"boredom","ru":"скука","vi":"sự nhàm chán","fa":"کسالت","examples":[{"de":"Aus Langeweile habe ich den ganzen Nachmittag ferngesehen.","en":"Out of boredom I watched television all afternoon.","ru":"От скуки я весь день смотрел телевизор.","vi":"Tôi xem TV cả buổi chiều vì chán.","fa":"تمام بعدازظهر از خستگی تلویزیون تماشا کردم."},{"de":"Bei diesem Vortrag kam keine Langeweile auf.","en":"There was no boredom during this lecture.","ru":"На этой лекции скучать не пришлось.","vi":"Không có sự nhàm chán trong suốt bài giảng này.","fa":"در طول این سخنرانی هیچ کسالتی وجود نداشت."},{"de":"Die Kinder kannten an dem Tag keine Langeweile.","en":"The children knew no boredom that day.","ru":"В тот день дети совсем не скучали.","vi":"Bọn trẻ không bao giờ chán ngày hôm đó.","fa":"بچه ها آن روز هیچ وقت حوصله نداشتند."}]},{"word":"langsam","en":"slow; slowly","ru":"медленный; медленно","vi":"từ từ","fa":"به آرامی","examples":[{"de":"Bitte sprich langsam, ich verstehe dich sonst nicht.","en":"Please speak slowly, otherwise I don't understand you.","ru":"Пожалуйста, говори медленно, иначе я тебя не пойму.","vi":"Hãy nói chậm lại, nếu không tôi sẽ không hiểu bạn.","fa":"لطفا آهسته صحبت کنید وگرنه من شما را درک نمی کنم."},{"de":"Der Zug fährt langsam in den Bahnhof ein.","en":"The train is slowly pulling into the station.","ru":"Поезд медленно въезжает на вокзал.","vi":"Đoàn tàu từ từ tiến vào ga.","fa":"قطار به آرامی وارد ایستگاه می شود."}]},{"word":"längst","en":"long ago; a long time ago","ru":"давно; уже давно","vi":"từ lâu rồi","fa":"خیلی وقت پیش","examples":[{"de":"Er wohnt schon längst nicht mehr hier.","en":"He hasn't lived here for a long time already.","ru":"Он уже давно здесь не живёт.","vi":"Anh ấy không còn sống ở đây nữa.","fa":"او دیگر اینجا زندگی نمی کند."},{"de":"Ich habe das Buch längst gelesen.","en":"I read the book a long time ago.","ru":"Я уже давно прочитал эту книгу.","vi":"Tôi đã đọc cuốn sách này từ lâu rồi.","fa":"من کتاب را خیلی وقت پیش خوانده بودم."}]},{"word":"die Langweile","en":"boredom (variant spelling of Langeweile)","ru":"скука (ошибочный вариант написания слова Langeweile)","vi":"sự nhàm chán","fa":"کسالت","examples":[{"de":"Manche Menschen schreiben fälschlich Langweile statt Langeweile.","en":"Some people wrongly write Langweile instead of Langeweile.","ru":"Некоторые ошибочно пишут Langweile вместо Langeweile.","vi":"Một số người viết nhầm là buồn chán thay vì buồn chán.","fa":"بعضی ها به اشتباه به جای حوصله، ملال می نویسند."},{"de":"Die Langweile im Wartezimmer war kaum auszuhalten.","en":"The boredom in the waiting room was almost unbearable.","ru":"Скука в приёмной была почти невыносимой.","vi":"Sự buồn chán trong phòng chờ gần như không thể chịu nổi.","fa":"کسالت در اتاق انتظار تقریبا غیر قابل تحمل بود."},{"de":"Vor Langweile begann er, mit dem Stift zu spielen.","en":"Out of boredom he started playing with the pen.","ru":"От скуки он начал играть с ручкой.","vi":"Vì chán nản, anh bắt đầu chơi với cây bút.","fa":"از خستگی شروع کرد به قلم بازی کردن."}]},{"word":"langweilen","en":"to bore; (reflexive) to be bored","ru":"наводить скуку; (возвр.) скучать","vi":"chán","fa":"بی حوصله","examples":[{"de":"Der Film hat mich sehr gelangweilt.","en":"The film bored me a lot.","ru":"Фильм меня очень утомил своей скукой.","vi":"Tôi rất chán bộ phim.","fa":"خیلی حوصله فیلم سر رفته بود."},{"de":"Die Kinder langweilen sich an Regentagen.","en":"The children get bored on rainy days.","ru":"Дети скучают в дождливые дни.","vi":"Những đứa trẻ buồn chán trong những ngày mưa.","fa":"بچه ها در روزهای بارانی حوصله شان سر می رود."},{"de":"Ich langweile mich nie in meinem Job.","en":"I am never bored in my job.","ru":"Мне никогда не бывает скучно на работе.","vi":"Tôi không bao giờ cảm thấy buồn chán trong công việc của mình.","fa":"من هرگز در کارم خسته نمی شوم."}]},{"word":"langweilig","en":"boring","ru":"скучный","vi":"nhạt nhẽo","fa":"خسته کننده","examples":[{"de":"Der Vortrag war ziemlich langweilig.","en":"The lecture was quite boring.","ru":"Лекция была довольно скучной.","vi":"Bài giảng khá nhàm chán.","fa":"سخنرانی بسیار خسته کننده بود."},{"de":"Ohne Freunde ist das Wochenende langweilig.","en":"Without friends the weekend is boring.","ru":"Без друзей выходные скучные.","vi":"Cuối tuần thật nhàm chán khi không có bạn bè.","fa":"آخر هفته بدون دوستان خسته کننده است."}]},{"word":"der Lärm","en":"the noise","ru":"шум","vi":"tiếng ồn","fa":"سر و صدا","examples":[{"de":"Der Lärm von der Baustelle stört mich.","en":"The noise from the construction site bothers me.","ru":"Шум со стройки меня раздражает.","vi":"Tiếng ồn từ công trường xây dựng làm tôi khó chịu.","fa":"صدای محل ساخت و ساز آزارم می دهد."},{"de":"Bei so viel Lärm kann ich nicht schlafen.","en":"I can't sleep with so much noise.","ru":"При таком шуме я не могу спать.","vi":"Tôi không thể ngủ được với quá nhiều tiếng ồn.","fa":"با این همه سر و صدا نمیتونم بخوابم"}]},{"word":"lassen","en":"to let; to leave","ru":"оставлять; позволять","vi":"hãy để","fa":"اجازه دهید","examples":[{"de":"Lass mich bitte in Ruhe.","en":"Please leave me alone.","ru":"Оставь меня, пожалуйста, в покое.","vi":"Xin hãy để tôi yên.","fa":"لطفا منو تنها بذار"},{"de":"Ich habe meinen Schirm im Bus gelassen.","en":"I left my umbrella on the bus.","ru":"Я оставил зонт в автобусе.","vi":"Tôi để quên ô trên xe buýt.","fa":"چترم را در اتوبوس جا گذاشتم."}]},{"word":"der Laster","en":"the truck","ru":"грузовик","vi":"xe tải","fa":"کامیون","examples":[{"de":"Der Laster transportiert Möbel.","en":"The truck transports furniture.","ru":"Грузовик перевозит мебель.","vi":"Xe tải chở đồ đạc.","fa":"کامیون حمل اثاثیه را انجام می دهد."},{"de":"Auf der Autobahn fuhr ein großer Laster vor uns.","en":"A big truck was driving in front of us on the highway.","ru":"На автостраде перед нами ехал большой грузовик.","vi":"Một chiếc xe tải lớn chạy trước mặt chúng tôi trên đường cao tốc.","fa":"یک کامیون بزرگ جلوی ما در بزرگراه حرکت کرد."}]},{"word":"laufen","en":"to run; to walk","ru":"бежать; идти пешком","vi":"chạy","fa":"اجرا کنید","examples":[{"de":"Jeden Morgen laufe ich eine Stunde im Park.","en":"Every morning I run for an hour in the park.","ru":"Каждое утро я бегаю час в парке.","vi":"Mỗi buổi sáng tôi chạy bộ một giờ trong công viên.","fa":"هر روز صبح یک ساعت در پارک می دوم."},{"de":"Wir sind zu Fuß zum Bahnhof gelaufen.","en":"We walked to the train station.","ru":"Мы пошли пешком на вокзал.","vi":"Chúng tôi đi bộ đến ga xe lửa.","fa":"به سمت ایستگاه قطار راه افتادیم."}]},{"word":"das Laufwerk","en":"the (disk) drive","ru":"дисковод; накопитель","vi":"ổ đĩa","fa":"درایو","examples":[{"de":"Bitte lege die CD in das Laufwerk ein.","en":"Please put the CD into the drive.","ru":"Пожалуйста, вставь диск в дисковод.","vi":"Vui lòng đưa đĩa CD vào ổ đĩa.","fa":"لطفا سی دی را داخل درایو قرار دهید."},{"de":"Mein Computer hat kein CD-Laufwerk mehr.","en":"My computer no longer has a CD drive.","ru":"В моём компьютере больше нет CD-дисковода.","vi":"Máy tính của tôi không còn ổ đĩa CD nữa.","fa":"کامپیوتر من دیگر درایو سی دی ندارد."}]},{"word":"die Laune","en":"the mood","ru":"настроение","vi":"tâm trạng","fa":"خلق و خوی","examples":[{"de":"Er hat heute schlechte Laune.","en":"He's in a bad mood today.","ru":"У него сегодня плохое настроение.","vi":"Hôm nay anh ấy có tâm trạng không tốt.","fa":"امروز حالش بد است."},{"de":"Gute Musik verbessert meine Laune.","en":"Good music improves my mood.","ru":"Хорошая музыка улучшает моё настроение.","vi":"Âm nhạc hay giúp cải thiện tâm trạng của tôi.","fa":"موسیقی خوب روحیه ام را بهتر می کند."}]},{"word":"laut","en":"loud","ru":"громкий","vi":"ồn ào","fa":"با صدای بلند","examples":[{"de":"Die Musik war viel zu laut.","en":"The music was much too loud.","ru":"Музыка была слишком громкой.","vi":"Âm nhạc quá ồn ào.","fa":"موسیقی خیلی بلند بود"},{"de":"Bitte sprich nicht so laut im Krankenhaus.","en":"Please don't speak so loudly in the hospital.","ru":"Пожалуйста, не говори так громко в больнице.","vi":"Xin đừng nói chuyện lớn tiếng trong bệnh viện.","fa":"لطفا در بیمارستان اینقدر بلند صحبت نکنید."}]},{"word":"der Lautsprecher","en":"the loudspeaker","ru":"громкоговоритель; динамик","vi":"người nói","fa":"سخنران","examples":[{"de":"Die Durchsage kam aus dem Lautsprecher am Bahnsteig.","en":"The announcement came from the loudspeaker on the platform.","ru":"Объявление прозвучало из громкоговорителя на платформе.","vi":"Thông báo được phát ra từ loa trên sân ga.","fa":"این اعلامیه از بلندگوی روی سکو منتشر شد."},{"de":"Wir haben neue Lautsprecher für die Musikanlage gekauft.","en":"We bought new speakers for the stereo system.","ru":"Мы купили новые динамики для музыкальной системы.","vi":"Chúng tôi đã mua loa mới cho hệ thống âm nhạc.","fa":"بلندگوهای جدیدی برای سیستم موسیقی خریدیم."}]},{"word":"leben","en":"to live","ru":"жить","vi":"sống","fa":"زندگی می کنند","examples":[{"de":"Meine Familie lebt in Berlin.","en":"My family lives in Berlin.","ru":"Моя семья живёт в Берлине.","vi":"Gia đình tôi sống ở Berlin.","fa":"خانواده من در برلین زندگی می کنند."},{"de":"Er möchte lange und gesund leben.","en":"He wants to live long and healthily.","ru":"Он хочет жить долго и здорово.","vi":"Ông muốn sống một cuộc sống lâu dài và khỏe mạnh.","fa":"او می خواهد زندگی طولانی و سالمی داشته باشد."}]},{"word":"die Lebenshaltungskosten","en":"cost of living (plural)","ru":"стоимость жизни, расходы на жизнь","vi":"chi phí sinh hoạt","fa":"هزینه زندگی","examples":[{"de":"Die Lebenshaltungskosten in der Stadt sind sehr hoch.","en":"The cost of living in the city is very high.","ru":"Стоимость жизни в городе очень высокая.","vi":"Chi phí sinh hoạt ở thành phố rất cao.","fa":"هزینه زندگی در شهر بسیار بالاست."},{"de":"Wegen der Inflation steigen die Lebenshaltungskosten.","en":"Because of inflation the cost of living is rising.","ru":"Из-за инфляции стоимость жизни растёт.","vi":"Vì lạm phát, chi phí sinh hoạt ngày càng tăng.","fa":"به دلیل تورم، هزینه زندگی در حال افزایش است."},{"de":"Viele Familien können die Lebenshaltungskosten kaum decken.","en":"Many families can barely cover the cost of living.","ru":"Многие семьи едва покрывают расходы на жизнь.","vi":"Nhiều gia đình hầu như không thể trang trải chi phí sinh hoạt.","fa":"بسیاری از خانواده ها به سختی می توانند هزینه های زندگی خود را تامین کنند."}]},{"word":"der Lebenslauf","en":"CV; résumé","ru":"резюме; биография","vi":"CV","fa":"رزومه","examples":[{"de":"Bitte schicken Sie uns Ihren Lebenslauf per E-Mail.","en":"Please send us your CV by email.","ru":"Пожалуйста, пришлите нам своё резюме по электронной почте.","vi":"Vui lòng gửi CV cho chúng tôi qua email.","fa":"لطفا رزومه خود را از طریق ایمیل برای ما ارسال کنید."},{"de":"Sein Lebenslauf ist lückenlos und übersichtlich.","en":"His CV is complete and clearly laid out.","ru":"Его резюме без пробелов и хорошо структурировано.","vi":"CV của anh ấy đầy đủ và rõ ràng.","fa":"رزومه او کامل و واضح است."}]},{"word":"die Lebensmittelvergiftung","en":"food poisoning","ru":"пищевое отравление","vi":"ngộ độc thực phẩm","fa":"مسمومیت غذایی","examples":[{"de":"Nach dem Essen im Hotel bekam sie eine Lebensmittelvergiftung.","en":"After eating at the hotel she got food poisoning.","ru":"После еды в отеле она получила пищевое отравление.","vi":"Cô bị ngộ độc thực phẩm sau khi ăn ở khách sạn.","fa":"او پس از صرف غذا در هتل دچار مسمومیت غذایی شد."},{"de":"Eine Lebensmittelvergiftung kann durch verdorbenes Fleisch entstehen.","en":"Food poisoning can be caused by spoiled meat.","ru":"Пищевое отравление может возникнуть из-за испорченного мяса.","vi":"Ngộ độc thực phẩm có thể xảy ra do thịt hư.","fa":"مسمومیت غذایی می تواند از گوشت فاسد ایجاد شود."},{"de":"Der Arzt vermutete eine leichte Lebensmittelvergiftung.","en":"The doctor suspected a mild case of food poisoning.","ru":"Врач заподозрил лёгкое пищевое отравление.","vi":"Bác sĩ nghi ngờ ngộ độc thực phẩm nhẹ.","fa":"دکتر مشکوک به مسمومیت غذایی خفیف بود."}]},{"word":"die Lebensqualität","en":"quality of life","ru":"качество жизни","vi":"chất lượng cuộc sống","fa":"کیفیت زندگی","examples":[{"de":"Die Lebensqualität ist hier sehr hoch.","en":"The quality of life here is very high.","ru":"Качество жизни здесь очень высокое.","vi":"Chất lượng cuộc sống ở đây rất cao.","fa":"کیفیت زندگی در اینجا بسیار بالاست."},{"de":"Grünflächen verbessern die Lebensqualität.","en":"Green spaces improve quality of life.","ru":"Зелёные зоны улучшают качество жизни.","vi":"Không gian xanh nâng cao chất lượng cuộc sống.","fa":"فضاهای سبز کیفیت زندگی را بهبود می بخشد."},{"de":"Geld allein steigert die Lebensqualität nicht.","en":"Money alone does not raise quality of life.","ru":"Одни деньги не повышают качество жизни.","vi":"Chỉ có tiền thôi thì không cải thiện được chất lượng cuộc sống.","fa":"پول به تنهایی کیفیت زندگی را بهبود نمی بخشد."}]},{"word":"die Lebensweise","en":"way of life, lifestyle","ru":"образ жизни","vi":"lối sống","fa":"راه زندگی","examples":[{"de":"Eine gesunde Lebensweise verlängert das Leben.","en":"A healthy way of life prolongs life.","ru":"Здоровый образ жизни продлевает жизнь.","vi":"Lối sống lành mạnh kéo dài tuổi thọ.","fa":"سبک زندگی سالم عمر را طولانی می کند."},{"de":"Ihre Lebensweise unterscheidet sich stark von meiner.","en":"Her way of life differs greatly from mine.","ru":"Её образ жизни сильно отличается от моего.","vi":"Cách sống của họ rất khác với tôi.","fa":"شیوه زندگی آنها با من بسیار متفاوت است."},{"de":"In der Stadt herrscht eine hektische Lebensweise.","en":"In the city there is a hectic way of life.","ru":"В городе царит суетливый образ жизни.","vi":"Có một lối sống bận rộn trong thành phố.","fa":"یک سبک زندگی پر هیجان در شهر وجود دارد."}]},{"word":"lecker","en":"delicious; tasty","ru":"вкусный","vi":"thơm ngon","fa":"خوشمزه","examples":[{"de":"Der Kuchen schmeckt wirklich lecker.","en":"The cake tastes really delicious.","ru":"Торт очень вкусный.","vi":"Bánh có hương vị thật sự rất ngon.","fa":"طعم کیک واقعا خوشمزه است."},{"de":"Meine Mutter kocht immer lecker.","en":"My mother always cooks deliciously.","ru":"Моя мама всегда готовит вкусно.","vi":"Mẹ tôi luôn nấu những món ăn ngon.","fa":"مادرم همیشه غذاهای خوشمزه درست می کند."}]},{"word":"das Leder","en":"the leather","ru":"кожа","vi":"da","fa":"چرم","examples":[{"de":"Diese Schuhe sind aus echtem Leder.","en":"These shoes are made of real leather.","ru":"Эта обувь сделана из настоящей кожи.","vi":"Những đôi giày này được làm bằng da thật.","fa":"این کفش ها از چرم طبیعی ساخته شده اند."},{"de":"Die Jacke aus Leder war sehr teuer.","en":"The leather jacket was very expensive.","ru":"Кожаная куртка была очень дорогой.","vi":"Chiếc áo khoác da rất đắt tiền.","fa":"کت چرم خیلی گرون بود."}]},{"word":"ledig","en":"single; unmarried","ru":"холостой; незамужняя","vi":"độc thân","fa":"مجرد","examples":[{"de":"Er ist noch ledig und hat keine Kinder.","en":"He is still single and has no children.","ru":"Он всё ещё холост и не имеет детей.","vi":"Anh vẫn độc thân và chưa có con.","fa":"او هنوز مجرد است و فرزندی ندارد."},{"de":"Im Formular musste sie ankreuzen, ob sie ledig oder verheiratet ist.","en":"In the form she had to check whether she is single or married.","ru":"В анкете ей нужно было отметить, не замужем она или замужем.","vi":"Trên mẫu đơn cô phải đánh dấu xem mình còn độc thân hay đã kết hôn.","fa":"در فرم باید تیک می زد که مجرد است یا متاهل."}]},{"word":"leer","en":"empty","ru":"пустой","vi":"trống rỗng","fa":"خالی","examples":[{"de":"Die Flasche ist schon leer.","en":"The bottle is already empty.","ru":"Бутылка уже пуста.","vi":"Cái chai đã trống rỗng.","fa":"بطری در حال حاضر خالی است."},{"de":"Der Bus war um diese Zeit fast leer.","en":"The bus was almost empty at this time.","ru":"Автобус в это время был почти пустым.","vi":"Lúc này xe buýt gần như trống rỗng.","fa":"اتوبوس در این زمان تقریبا خالی بود."}]},{"word":"legen","en":"to lay; to put","ru":"класть; положить","vi":"nằm","fa":"دراز کشیدن","examples":[{"de":"Sie legt das Buch auf den Tisch.","en":"She puts the book on the table.","ru":"Она кладёт книгу на стол.","vi":"Cô đặt cuốn sách lên bàn.","fa":"کتاب را روی میز می گذارد."},{"de":"Er legte sich müde ins Bett.","en":"He lay down in bed, tired.","ru":"Он устало лёг в постель.","vi":"Anh mệt mỏi đi ngủ.","fa":"خسته به رختخواب رفت."}]},{"word":"die Lehre","en":"the apprenticeship; the lesson","ru":"обучение (профессии); урок","vi":"việc giảng dạy","fa":"آموزش","examples":[{"de":"Nach der Schule beginnt sie eine Lehre als Bäckerin.","en":"After school she begins an apprenticeship as a baker.","ru":"После школы она начинает обучение на пекаря.","vi":"Sau giờ học, cô bắt đầu học nghề làm bánh.","fa":"پس از مدرسه، او به عنوان یک نانوا کارآموزی را آغاز می کند."},{"de":"Aus diesem Fehler sollten wir eine Lehre ziehen.","en":"We should learn a lesson from this mistake.","ru":"Из этой ошибки нам следует извлечь урок.","vi":"Chúng ta nên rút ra bài học từ sai lầm này.","fa":"ما باید از این اشتباه درس بگیریم."}]},{"word":"der Lehrer","en":"the teacher","ru":"учитель","vi":"giáo viên","fa":"معلم","examples":[{"de":"Unser Lehrer erklärt die Grammatik sehr gut.","en":"Our teacher explains grammar very well.","ru":"Наш учитель очень хорошо объясняет грамматику.","vi":"Giáo viên của chúng tôi giải thích ngữ pháp rất tốt.","fa":"معلم ما گرامر را خیلی خوب توضیح می دهد."},{"de":"Sie möchte später Lehrerin werden.","en":"She wants to become a teacher later.","ru":"Она хочет позже стать учительницей.","vi":"Cô ấy muốn trở thành một giáo viên khi lớn lên.","fa":"او می خواهد وقتی بزرگ شد معلم شود."}]},{"word":"die Lehrerin","en":"teacher (female)","ru":"учительница, преподавательница","vi":"giáo viên","fa":"معلم","examples":[{"de":"Unsere Lehrerin erklärt die Grammatik sehr verständlich.","en":"Our teacher explains the grammar very clearly.","ru":"Наша учительница очень понятно объясняет грамматику.","vi":"Giáo viên của chúng tôi giải thích ngữ pháp rất rõ ràng.","fa":"معلم ما گرامر را خیلی واضح توضیح می دهد."},{"de":"Die Lehrerin korrigiert am Wochenende die Tests.","en":"The teacher corrects the tests at the weekend.","ru":"Учительница проверяет контрольные по выходным.","vi":"Giáo viên sửa bài kiểm tra vào cuối tuần.","fa":"معلم در آخر هفته تست ها را تصحیح می کند."},{"de":"Meine Lehrerin hat mir bei den Hausaufgaben geholfen.","en":"My teacher helped me with the homework.","ru":"Моя учительница помогла мне с домашним заданием.","vi":"Giáo viên của tôi đã giúp tôi làm bài tập về nhà.","fa":"معلمم در انجام تکالیف به من کمک کرد."}]},{"word":"der Lehrling","en":"the apprentice","ru":"ученик (в профессии)","vi":"người học việc","fa":"شاگرد","examples":[{"de":"Der Lehrling lernt das Handwerk vom Meister.","en":"The apprentice learns the craft from the master.","ru":"Ученик учится ремеслу у мастера.","vi":"Người học việc học nghề từ bậc thầy.","fa":"شاگرد این کار را از استاد یاد می گیرد."},{"de":"Als Lehrling verdient man noch nicht viel Geld.","en":"As an apprentice you don't earn much money yet.","ru":"Будучи учеником, зарабатываешь ещё немного денег.","vi":"Là một người học việc, bạn không kiếm được nhiều tiền.","fa":"به عنوان یک شاگرد، شما پول زیادی کسب نمی کنید."}]},{"word":"die Lehrstelle","en":"apprenticeship position; training place","ru":"место для профессионального обучения, ученическое место","vi":"việc học nghề","fa":"کارآموزی","examples":[{"de":"Er sucht eine Lehrstelle als Mechaniker.","en":"He is looking for an apprenticeship as a mechanic.","ru":"Он ищет место обучения на механика.","vi":"Anh ấy đang muốn học nghề làm thợ cơ khí.","fa":"او به دنبال کارآموزی مکانیک است."},{"de":"Die Firma bietet jedes Jahr mehrere Lehrstellen an.","en":"The company offers several apprenticeship positions every year.","ru":"Компания ежегодно предлагает несколько мест для обучения.","vi":"Công ty cung cấp nhiều khóa học nghề mỗi năm.","fa":"این شرکت هر ساله چندین دوره کارآموزی ارائه می دهد."},{"de":"Endlich hat sie eine Lehrstelle gefunden.","en":"At last she has found an apprenticeship position.","ru":"Наконец-то она нашла место для обучения.","vi":"Cuối cùng cô đã tìm được một người học nghề.","fa":"بالاخره شاگردی پیدا کرد."}]},{"word":"leicht","en":"light; easy","ru":"лёгкий","vi":"dễ dàng","fa":"به راحتی","examples":[{"de":"Diese Tasche ist sehr leicht.","en":"This bag is very light.","ru":"Эта сумка очень лёгкая.","vi":"Chiếc túi này rất nhẹ.","fa":"این کیف بسیار سبک است."},{"de":"Die Prüfung war leichter als erwartet.","en":"The exam was easier than expected.","ru":"Экзамен был легче, чем ожидалось.","vi":"Bài kiểm tra dễ dàng hơn mong đợi.","fa":"آزمون راحت تر از حد انتظار بود."}]},{"word":"leichtfallen","en":"to come easily, to be easy (for someone)","ru":"легко даваться (кому-либо)","vi":"đến dễ dàng","fa":"راحت بیا","examples":[{"de":"Mathematik fällt mir leicht.","en":"Maths comes easily to me.","ru":"Математика даётся мне легко.","vi":"Toán học thật dễ dàng đối với tôi.","fa":"ریاضیات برای من آسان است."},{"de":"Das Lernen fiel ihr schon immer leicht.","en":"Learning has always come easily to her.","ru":"Учёба всегда давалась ей легко.","vi":"Việc học luôn luôn dễ dàng đối với cô.","fa":"یادگیری همیشه برای او آسان بوده است."},{"de":"Es fällt mir nicht leicht, früh aufzustehen.","en":"It isn't easy for me to get up early.","ru":"Мне нелегко вставать рано.","vi":"Đối với tôi, việc dậy sớm không phải dễ dàng.","fa":"زود بیدار شدن برای من آسان نیست."}]},{"word":"leid tun","en":"to be sorry","ru":"быть жаль (кому-то)","vi":"làm tổn thương","fa":"صدمه زدن","examples":[{"de":"Es tut mir leid, dass ich zu spät komme.","en":"I'm sorry that I'm coming late.","ru":"Мне жаль, что я опаздываю.","vi":"Tôi xin lỗi tôi đến muộn.","fa":"ببخشید دیر اومدم"},{"de":"Tut dir das nicht leid?","en":"Aren't you sorry about that?","ru":"Тебе разве не жаль этого?","vi":"Bạn không tiếc về điều đó sao?","fa":"از این بابت متاسف نیستی؟"}]},{"word":"leiden","en":"to suffer","ru":"страдать","vi":"đau khổ","fa":"رنج می برند","examples":[{"de":"Sie leidet seit Jahren an Kopfschmerzen.","en":"She has been suffering from headaches for years.","ru":"Она годами страдает от головных болей.","vi":"Cô ấy bị chứng đau đầu trong nhiều năm.","fa":"او سال ها از سردرد رنج می برد."},{"de":"Viele Menschen leiden unter der Hitze.","en":"Many people suffer from the heat.","ru":"Многие люди страдают от жары.","vi":"Nhiều người phải chịu đựng cái nóng.","fa":"بسیاری از مردم از گرما رنج می برند."}]},{"word":"leider","en":"unfortunately","ru":"к сожалению","vi":"thật không may","fa":"متاسفانه","examples":[{"de":"Leider kann ich morgen nicht kommen.","en":"Unfortunately, I can't come tomorrow.","ru":"К сожалению, я не смогу прийти завтра.","vi":"Thật không may là tôi không thể đến vào ngày mai.","fa":"متاسفانه فردا نمیتونم بیام"},{"de":"Das Wetter war leider sehr schlecht.","en":"Unfortunately the weather was very bad.","ru":"К сожалению, погода была очень плохой.","vi":"Thật không may, thời tiết rất xấu.","fa":"متاسفانه هوا خیلی بد بود."}]},{"word":"leihen","en":"to lend; to borrow","ru":"одалживать","vi":"mượn","fa":"قرض گرفتن","examples":[{"de":"Kannst du mir zwanzig Euro leihen?","en":"Can you lend me twenty euros?","ru":"Можешь одолжить мне двадцать евро?","vi":"Bạn có thể cho tôi mượn hai mươi euro được không?","fa":"میشه بیست یورو به من قرض بدی؟"},{"de":"Ich habe mir ein Buch aus der Bibliothek geliehen.","en":"I borrowed a book from the library.","ru":"Я взял книгу в библиотеке.","vi":"Tôi mượn một cuốn sách từ thư viện.","fa":"یک کتاب از کتابخانه امانت گرفتم."}]},{"word":"leise","en":"quiet; soft","ru":"тихий","vi":"lặng lẽ","fa":"بی سر و صدا","examples":[{"de":"Bitte sei leise, das Baby schläft.","en":"Please be quiet, the baby is sleeping.","ru":"Пожалуйста, тише, ребёнок спит.","vi":"Xin hãy im lặng, em bé đang ngủ.","fa":"لطفا ساکت باش بچه خوابه"},{"de":"Sie sprach so leise, dass ich sie kaum hörte.","en":"She spoke so quietly that I could barely hear her.","ru":"Она говорила так тихо, что я едва её слышал.","vi":"Cô ấy nói nhỏ đến mức tôi khó có thể nghe thấy.","fa":"آنقدر آرام صحبت می کرد که من به سختی می توانستم صدایش را بشنوم."}]},{"word":"leisten","en":"to achieve; to afford","ru":"выполнять; позволить себе","vi":"đủ khả năng","fa":"استطاعت","examples":[{"de":"Er hat in seinem Beruf viel geleistet.","en":"He has achieved a lot in his profession.","ru":"Он многого добился в своей профессии.","vi":"Anh ấy đã đạt được rất nhiều thành tựu trong nghề nghiệp của mình.","fa":"او در حرفه خود به موفقیت های زیادی دست یافته است."},{"de":"Wir können uns diesen Urlaub leider nicht leisten.","en":"Unfortunately, we can't afford this vacation.","ru":"К сожалению, мы не можем позволить себе этот отпуск.","vi":"Thật không may, chúng tôi không đủ khả năng cho kỳ nghỉ này.","fa":"متأسفانه ما نمی توانیم این تعطیلات را بپردازیم."}]},{"word":"die Leistung","en":"performance; achievement","ru":"достижение; производительность","vi":"hiệu suất","fa":"عملکرد","examples":[{"de":"Seine Leistung im Test war ausgezeichnet.","en":"His performance in the test was excellent.","ru":"Его результат на тесте был отличным.","vi":"Thành tích của anh ấy trong bài kiểm tra rất xuất sắc.","fa":"عملکرد او در آزمون عالی بود."},{"de":"Für diese Leistung bekam sie einen Preis.","en":"She received an award for this achievement.","ru":"За это достижение она получила награду.","vi":"Cô đã nhận được giải thưởng cho thành tích này.","fa":"او برای این موفقیت جایزه دریافت کرد."}]},{"word":"leiten","en":"to lead; to manage","ru":"руководить; вести","vi":"hướng dẫn","fa":"راهنمای","examples":[{"de":"Frau Schmidt leitet die Abteilung seit zwei Jahren.","en":"Ms. Schmidt has been leading the department for two years.","ru":"Госпожа Шмидт руководит отделом уже два года.","vi":"Bà Schmidt đã đứng đầu bộ phận này được hai năm.","fa":"خانم اشمیت به مدت دو سال ریاست این بخش را بر عهده داشته است."},{"de":"Wer leitet dieses Projekt?","en":"Who is managing this project?","ru":"Кто руководит этим проектом?","vi":"Ai đang lãnh đạo dự án này?","fa":"چه کسی این پروژه را هدایت می کند؟"}]},{"word":"die Leiter","en":"the ladder","ru":"лестница (приставная)","vi":"cái thang","fa":"نردبان","examples":[{"de":"Er stieg auf die Leiter, um die Lampe zu wechseln.","en":"He climbed the ladder to change the lamp.","ru":"Он забрался на лестницу, чтобы поменять лампу.","vi":"Anh leo lên thang để thay đèn.","fa":"از نردبان بالا رفت تا چراغ را عوض کند."},{"de":"Die Leiter steht an der Wand.","en":"The ladder is standing against the wall.","ru":"Лестница стоит у стены.","vi":"Cái thang dựa vào tường.","fa":"نردبان به دیوار است."}]},{"word":"die Leiterin","en":"head; manager; director (female)","ru":"руководительница, начальница, заведующая; директор (о женщине)","vi":"người lãnh đạo","fa":"رهبر","examples":[{"de":"Die Leiterin der Abteilung hält jeden Montag eine Besprechung.","en":"The head of the department holds a meeting every Monday.","ru":"Руководительница отдела проводит совещание каждый понедельник.","vi":"Người đứng đầu bộ phận tổ chức một cuộc họp vào thứ Hai hàng tuần.","fa":"رئیس اداره هر دوشنبه جلسه ای برگزار می کند."},{"de":"Unsere neue Leiterin hat viele gute Ideen.","en":"Our new manager has many good ideas.","ru":"У нашей новой начальницы много хороших идей.","vi":"Lãnh đạo mới của chúng ta có rất nhiều ý tưởng hay.","fa":"رهبر جدید ما ایده های خوبی دارد."},{"de":"Die Leiterin des Kindergartens kennt jedes Kind beim Namen.","en":"The head of the nursery knows every child by name.","ru":"Заведующая детским садом знает каждого ребёнка по имени.","vi":"Người đứng đầu trường mẫu giáo biết tên từng đứa trẻ.","fa":"رئیس مهدکودک هر کودکی را به نام می شناسد."}]},{"word":"die Leitung","en":"management; leadership; line (cable/pipe)","ru":"руководство; управление; провод, линия (кабель/труба)","vi":"dòng","fa":"خط","examples":[{"de":"Die Leitung der Firma hat eine neue Regel beschlossen.","en":"The management of the company has decided on a new rule.","ru":"Руководство компании приняло новое правило.","vi":"Ban quản lý công ty đã quyết định một quy định mới.","fa":"مدیریت شرکت در مورد یک قانون جدید تصمیم گرفته است."},{"de":"Unter ihrer Leitung läuft das Projekt sehr gut.","en":"Under her leadership the project is going very well.","ru":"Под её руководством проект идёт очень хорошо.","vi":"Dưới sự lãnh đạo của cô, dự án đang tiến triển rất tốt.","fa":"تحت رهبری او این پروژه بسیار خوب پیش می رود."},{"de":"Die Leitung ist besetzt, bitte rufen Sie später an.","en":"The line is busy, please call again later.","ru":"Линия занята, перезвоните, пожалуйста, позже.","vi":"Đường dây đang bận, vui lòng gọi lại sau.","fa":"خط مشغول است لطفا بعدا تماس بگیرید"}]},{"word":"lenken","en":"to steer, to direct","ru":"управлять, направлять; рулить","vi":"trực tiếp","fa":"مستقیم","examples":[{"de":"Er lenkt das Auto sicher durch den Verkehr.","en":"He steers the car safely through the traffic.","ru":"Он уверенно ведёт машину сквозь поток.","vi":"Anh ấy điều khiển xe an toàn khi tham gia giao thông.","fa":"او با خیال راحت ماشین را در ترافیک هدایت می کند."},{"de":"Die Werbung lenkt unsere Aufmerksamkeit auf das Produkt.","en":"The advertisement directs our attention to the product.","ru":"Реклама направляет наше внимание на товар.","vi":"Quảng cáo thu hút sự chú ý của chúng ta đến sản phẩm.","fa":"تبلیغات توجه ما را به محصول جلب می کند."},{"de":"Bitte lenk mich nicht beim Fahren ab.","en":"Please don't distract me while driving.","ru":"Пожалуйста, не отвлекай меня во время вождения.","vi":"Làm ơn đừng làm tôi phân tâm khi đang lái xe.","fa":"لطفا در حین رانندگی حواس من را پرت نکنید."}]},{"word":"lernen","en":"to learn","ru":"учить(ся)","vi":"học hỏi","fa":"یاد بگیرند","examples":[{"de":"Sie lernt seit einem Jahr Deutsch.","en":"She has been learning German for a year.","ru":"Она учит немецкий уже год.","vi":"Cô ấy đã học tiếng Đức được một năm.","fa":"او یک سال است که آلمانی یاد می گیرد."},{"de":"Ich muss heute Abend für die Prüfung lernen.","en":"I have to study for the exam tonight.","ru":"Мне нужно сегодня вечером готовиться к экзамену.","vi":"Tối nay tôi phải học bài thi.","fa":"امشب باید برای امتحان بخونم."}]},{"word":"der Lerner","en":"learner","ru":"учащийся, обучающийся","vi":"người học","fa":"زبان آموز","examples":[{"de":"Ein guter Lerner stellt viele Fragen.","en":"A good learner asks lots of questions.","ru":"Хороший учащийся задаёт много вопросов.","vi":"Một người học giỏi đặt rất nhiều câu hỏi.","fa":"یک زبان آموز خوب سوالات زیادی می پرسد."},{"de":"Dieses Buch ist besonders für junge Lerner geeignet.","en":"This book is especially suitable for young learners.","ru":"Эта книга особенно подходит для юных учащихся.","vi":"Cuốn sách này đặc biệt phù hợp với những người mới học.","fa":"این کتاب به ویژه برای دانش آموزان جوان مناسب است."},{"de":"Der Lerner macht beim Sprechen langsam Fortschritte.","en":"The learner is slowly making progress in speaking.","ru":"Учащийся постепенно делает успехи в разговоре.","vi":"Người học tiến bộ chậm trong việc nói.","fa":"زبان آموز در صحبت کردن به کندی پیشرفت می کند."}]},{"word":"die Lernerin","en":"learner (female)","ru":"учащаяся, обучающаяся (женщина)","vi":"người học","fa":"زبان آموز","examples":[{"de":"Die Lernerin notiert sich jedes neue Wort.","en":"The learner writes down every new word.","ru":"Учащаяся записывает каждое новое слово.","vi":"Người học viết ra từng từ mới.","fa":"زبان آموز هر کلمه جدید را یادداشت می کند."},{"de":"Als Lernerin findet sie das Hörverstehen am schwierigsten.","en":"As a learner she finds listening comprehension the most difficult.","ru":"Как учащейся, ей труднее всего даётся аудирование.","vi":"Là một người học, cô nhận thấy phần nghe hiểu là phần khó nhất.","fa":"به عنوان یک زبان آموز، او درک شنیداری را سخت ترین بخش می داند."},{"de":"Die fleißige Lernerin übt jeden Tag.","en":"The diligent learner practises every day.","ru":"Прилежная учащаяся занимается каждый день.","vi":"Những người học chăm chỉ luyện tập mỗi ngày.","fa":"یادگیرنده سخت کوش هر روز تمرین می کند."}]},{"word":"das Lernziel","en":"learning objective; learning goal","ru":"учебная цель","vi":"mục tiêu học tập","fa":"هدف یادگیری","examples":[{"de":"Das Lernziel dieses Kurses ist flüssiges Sprechen.","en":"The learning objective of this course is fluent speaking.","ru":"Учебная цель этого курса — свободная речь.","vi":"Mục tiêu học tập của khóa học này là nói trôi chảy.","fa":"هدف یادگیری این دوره فن بیان می باشد."},{"de":"Am Anfang der Stunde nennt die Lehrerin das Lernziel.","en":"At the start of the lesson the teacher states the learning objective.","ru":"В начале урока учитель называет учебную цель.","vi":"Đầu bài giáo viên nêu mục tiêu bài học.","fa":"در ابتدای درس معلم هدف یادگیری را بیان می کند."},{"de":"Wir haben unser Lernziel für heute schon erreicht.","en":"We have already reached our learning goal for today.","ru":"Свою учебную цель на сегодня мы уже достигли.","vi":"Chúng tôi đã đạt được mục tiêu học tập của mình cho ngày hôm nay.","fa":"ما قبلاً به هدف یادگیری امروز خود رسیده ایم."}]},{"word":"lesen","en":"to read","ru":"читать","vi":"đọc","fa":"خواندن","examples":[{"de":"Er liest jeden Abend eine Zeitung.","en":"He reads a newspaper every evening.","ru":"Он каждый вечер читает газету.","vi":"Anh ấy đọc báo mỗi tối.","fa":"او هر روز عصر یک روزنامه می خواند."},{"de":"Hast du das neue Buch schon gelesen?","en":"Have you already read the new book?","ru":"Ты уже прочитал новую книгу?","vi":"Bạn đã đọc cuốn sách mới chưa?","fa":"آیا هنوز کتاب جدید را خوانده اید؟"}]},{"word":"der Leser","en":"reader","ru":"читатель","vi":"người đọc","fa":"خواننده","examples":[{"de":"Die Zeitung hat über eine Million Leser.","en":"The newspaper has over a million readers.","ru":"У газеты больше миллиона читателей.","vi":"Tờ báo có hơn một triệu độc giả.","fa":"این روزنامه بیش از یک میلیون خواننده دارد."},{"de":"Der Autor bedankte sich bei seinen treuen Lesern.","en":"The author thanked his loyal readers.","ru":"Автор поблагодарил своих верных читателей.","vi":"Tác giả cảm ơn những độc giả trung thành của mình.","fa":"نویسنده از خوانندگان وفادار خود تشکر کرد."},{"de":"Viele Leser schrieben Briefe an die Redaktion.","en":"Many readers wrote letters to the editorial team.","ru":"Многие читатели написали письма в редакцию.","vi":"Nhiều độc giả đã viết thư cho biên tập viên.","fa":"بسیاری از خوانندگان به سردبیر نامه نوشتند."}]},{"word":"die Leserin","en":"reader (female)","ru":"читательница","vi":"người đọc","fa":"خواننده","examples":[{"de":"Die Leserin schickte einen Kommentar an die Zeitschrift.","en":"The reader sent a comment to the magazine.","ru":"Читательница отправила отзыв в журнал.","vi":"Người đọc đã gửi bình luận cho tạp chí.","fa":"خواننده نظری را برای مجله ارسال کرد."},{"de":"Eine begeisterte Leserin empfahl mir diesen Roman.","en":"An enthusiastic reader recommended this novel to me.","ru":"Одна восторженная читательница порекомендовала мне этот роман.","vi":"Một độc giả nhiệt tình đã giới thiệu cuốn tiểu thuyết này cho tôi.","fa":"یک خواننده مشتاق این رمان را به من توصیه کرد."},{"de":"Die Leserin konnte das Buch nicht aus der Hand legen.","en":"The reader could not put the book down.","ru":"Читательница не могла оторваться от книги.","vi":"Người đọc không thể đặt cuốn sách xuống.","fa":"خواننده نتوانست کتاب را زمین بگذارد."}]},{"word":"letzt-","en":"last","ru":"последний","vi":"cuối cùng-","fa":"آخرین-","examples":[{"de":"Das war ihr letzter Arbeitstag vor der Rente.","en":"That was her last working day before retirement.","ru":"Это был её последний рабочий день перед пенсией.","vi":"Đó là ngày làm việc cuối cùng của cô trước khi nghỉ hưu.","fa":"این آخرین روز کاری او قبل از بازنشستگی بود."},{"de":"Wir haben uns das letzte Mal vor zwei Jahren gesehen.","en":"We last saw each other two years ago.","ru":"Мы виделись в последний раз два года назад.","vi":"Lần cuối cùng chúng tôi gặp nhau là hai năm trước.","fa":"آخرین بار همدیگر را دو سال پیش دیدیم."}]},{"word":"die Leute","en":"people","ru":"люди","vi":"mọi người","fa":"مردم","examples":[{"de":"Auf dem Markt waren viele Leute.","en":"There were many people at the market.","ru":"На рынке было много людей.","vi":"Trong chợ đã có rất nhiều người.","fa":"افراد زیادی در بازار بودند."},{"de":"Die Leute in diesem Dorf sind sehr freundlich.","en":"The people in this village are very friendly.","ru":"Люди в этой деревне очень дружелюбны.","vi":"Người dân ở ngôi làng này rất thân thiện.","fa":"مردم این روستا بسیار صمیمی هستند."}]},{"word":"das Lexikon","en":"the encyclopedia; the dictionary","ru":"энциклопедия; словарь","vi":"từ vựng","fa":"واژگان","examples":[{"de":"Er hat das Wort im Lexikon nachgeschlagen.","en":"He looked up the word in the dictionary.","ru":"Он посмотрел слово в словаре.","vi":"Anh tra từ đó trong từ điển.","fa":"او کلمه را در فرهنگ لغت جستجو کرد."},{"de":"Zu Hause haben wir ein großes Lexikon.","en":"At home we have a large encyclopedia.","ru":"Дома у нас есть большая энциклопедия.","vi":"Chúng tôi có một bộ bách khoa toàn thư lớn ở nhà.","fa":"ما یک دایره المعارف بزرگ در خانه داریم."}]},{"word":"das Licht","en":"the light","ru":"свет","vi":"ánh sáng","fa":"نور","examples":[{"de":"Bitte mach das Licht aus, wenn du gehst.","en":"Please turn off the light when you leave.","ru":"Пожалуйста, выключи свет, когда уйдёшь.","vi":"Vui lòng tắt đèn khi bạn rời đi.","fa":"لطفاً هنگام خروج چراغ ها را خاموش کنید."},{"de":"Am Abend fällt warmes Licht durch das Fenster.","en":"In the evening warm light falls through the window.","ru":"Вечером тёплый свет падает через окно.","vi":"Vào buổi tối, ánh sáng ấm áp chiếu qua cửa sổ.","fa":"در شب، نور گرم از پنجره می تابد."}]},{"word":"der Lichtblitz","en":"flash of light","ru":"вспышка света","vi":"tia sáng","fa":"the flash of light","examples":[{"de":"Ein heller Lichtblitz erschien plötzlich am Nachthimmel.","en":"A bright flash of light suddenly appeared in the night sky.","ru":"Яркая вспышка света внезапно появилась в ночном небе.","vi":"Một tia sáng đột nhiên xuất hiện trên bầu trời đêm.","fa":"نور درخشانی ناگهان در آسمان شب ظاهر شد."},{"de":"Der Lichtblitz kam von einem explodierenden Stern.","en":"The flash of light came from an exploding star.","ru":"Вспышка света исходила от взрывающейся звезды.","vi":"Ánh sáng lóe lên từ một ngôi sao đang phát nổ.","fa":"فلش نور از یک ستاره در حال انفجار آمد."},{"de":"Astronomen registrierten einen kurzen Lichtblitz im All.","en":"Astronomers recorded a brief flash of light in space.","ru":"Астрономы зарегистрировали короткую вспышку света в космосе.","vi":"Các nhà thiên văn học đã ghi nhận một tia sáng ngắn ngủi trong không gian.","fa":"ستاره شناسان یک فلش نوری کوتاه در فضا ثبت کردند."}]},{"word":"die Lichtgeschwindigkeit","en":"speed of light","ru":"скорость света","vi":"tốc độ ánh sáng","fa":"سرعت نور","examples":[{"de":"Nichts ist schneller als die Lichtgeschwindigkeit.","en":"Nothing is faster than the speed of light.","ru":"Нет ничего быстрее скорости света.","vi":"Không có gì nhanh hơn tốc độ ánh sáng.","fa":"هیچ چیز سریعتر از سرعت نور نیست."},{"de":"Das Licht der Sonne braucht acht Minuten bis zur Erde.","en":"The Sun's light takes eight minutes to reach the Earth.","ru":"Свету Солнца нужно восемь минут, чтобы достичь Земли.","vi":"Ánh sáng từ mặt trời mất tám phút để đến được trái đất.","fa":"نور خورشید هشت دقیقه طول می کشد تا به زمین برسد."},{"de":"Mit Lichtgeschwindigkeit wäre man in Sekunden auf dem Mond.","en":"At the speed of light you would be on the Moon in seconds.","ru":"На скорости света ты был бы на Луне за секунды.","vi":"Với tốc độ ánh sáng, bạn sẽ ở trên mặt trăng trong vài giây.","fa":"با سرعت نور در عرض چند ثانیه روی ماه خواهید بود."}]},{"word":"lieb","en":"dear; kind","ru":"милый; дорогой","vi":"thân yêu","fa":"عزیز","examples":[{"de":"Sie ist ein sehr liebes Mädchen.","en":"She is a very sweet girl.","ru":"Она очень милая девочка.","vi":"Cô ấy là một cô gái rất ngọt ngào.","fa":"او یک دختر بسیار شیرین است."},{"de":"Liebe Grüße aus dem Urlaub!","en":"Dear greetings from vacation!","ru":"Дорогой привет из отпуска!","vi":"Lời chào từ kỳ nghỉ!","fa":"سلام از تعطیلات!"}]},{"word":"lieben","en":"to love","ru":"любить","vi":"tình yêu","fa":"عشق","examples":[{"de":"Ich liebe meine Familie über alles.","en":"I love my family more than anything.","ru":"Я люблю свою семью больше всего на свете.","vi":"Tôi yêu gia đình mình hơn bất cứ điều gì.","fa":"من خانواده ام را بیشتر از هر چیزی دوست دارم."},{"de":"Sie lieben sich seit der Schulzeit.","en":"They have loved each other since school days.","ru":"Они любят друг друга со школьных лет.","vi":"Họ yêu nhau từ khi còn đi học.","fa":"آنها از دوران مدرسه همدیگر را دوست داشتند."}]},{"word":"Lieber nicht","en":"I'd rather not (polite refusal)","ru":"Лучше не надо (вежливый отказ)","vi":"Tôi thà không","fa":"من ترجیح می دهم نه","examples":[{"de":"Lieber nicht, ich habe keine Zeit.","en":"I'd rather not, I don't have time.","ru":"Лучше не надо, у меня нет времени.","vi":"Tôi không muốn, tôi không có thời gian.","fa":"ترجیح میدم نه، وقت ندارم."}]},{"word":"das Liebes","en":"sweetheart, darling (term of endearment); something nice/good","ru":"милый, дорогой (ласковое обращение); что-то приятное, хорошее","vi":"người thân yêu","fa":"عزیز","examples":[{"de":"Komm her, mein Liebes, ich habe dich vermisst.","en":"Come here, my darling, I've missed you.","ru":"Иди сюда, дорогой мой, я по тебе соскучилась.","vi":"Hãy đến đây, tình yêu của anh, anh nhớ em.","fa":"بیا اینجا عشقم دلم برات تنگ شده بود"},{"de":"Hast du Liebes für mich dabei?","en":"Have you brought something nice for me?","ru":"Ты принёс мне что-нибудь хорошенькое?","vi":"Bạn có tình yêu với tôi không?","fa":"آیا به من عشق داری؟"},{"de":"Gute Nacht, mein Liebes, schlaf gut.","en":"Good night, my sweetheart, sleep well.","ru":"Спокойной ночи, милый мой, спи сладко.","vi":"Chúc ngủ ngon, tình yêu của anh, ngủ ngon nhé.","fa":"شب بخیر عشقم خوب بخواب"}]},{"word":"das Lied","en":"the song","ru":"песня","vi":"bài hát","fa":"آهنگ","examples":[{"de":"Die Kinder singen ein bekanntes Lied.","en":"The children are singing a well-known song.","ru":"Дети поют известную песню.","vi":"Trẻ hát một bài hát quen thuộc.","fa":"بچه ها آهنگ معروفی می خوانند."},{"de":"Dieses Lied hören wir im Radio ständig.","en":"We hear this song on the radio all the time.","ru":"Мы постоянно слышим эту песню по радио.","vi":"Chúng tôi nghe bài hát này trên radio mọi lúc.","fa":"ما همیشه این آهنگ را از رادیو می شنویم."}]},{"word":"liefern","en":"to deliver","ru":"поставлять; доставлять","vi":"giao hàng","fa":"تحویل دهید","examples":[{"de":"Die Firma liefert die Möbel nächste Woche.","en":"The company will deliver the furniture next week.","ru":"Компания доставит мебель на следующей неделе.","vi":"Công ty sẽ giao đồ nội thất vào tuần tới.","fa":"این شرکت مبلمان را هفته آینده تحویل خواهد داد."},{"de":"Der Pizzabote liefert das Essen direkt nach Hause.","en":"The pizza delivery person delivers the food right to your home.","ru":"Курьер доставляет еду прямо домой.","vi":"Cậu bé giao bánh pizza giao đồ ăn trực tiếp đến nhà bạn.","fa":"پسر تحویل پیتزا غذا را مستقیماً به خانه شما تحویل می دهد."}]},{"word":"die Lieferoption","en":"delivery option","ru":"вариант доставки","vi":"tùy chọn giao hàng","fa":"گزینه تحویل","examples":[{"de":"Welche Lieferoption ist für dich am günstigsten?","en":"Which delivery option is cheapest for you?","ru":"Какой вариант доставки для тебя самый дешёвый?","vi":"Lựa chọn giao hàng nào là rẻ nhất cho bạn?","fa":"کدام گزینه تحویل برای شما ارزان ترین است؟"},{"de":"Beim Bezahlen kannst du die Lieferoption ändern.","en":"At checkout you can change the delivery option.","ru":"При оформлении заказа можно изменить вариант доставки.","vi":"Bạn có thể thay đổi tùy chọn giao hàng khi thanh toán.","fa":"شما می توانید گزینه تحویل را هنگام بررسی تغییر دهید."},{"de":"Die schnellste Lieferoption kostet leider extra.","en":"The fastest delivery option unfortunately costs extra.","ru":"Самый быстрый вариант доставки, к сожалению, стоит дороже.","vi":"Thật không may, tùy chọn giao hàng nhanh nhất sẽ phải trả thêm phí.","fa":"متأسفانه، سریعترین گزینه تحویل هزینه اضافی دارد."}]},{"word":"liegen","en":"to lie; to be located","ru":"лежать; находиться","vi":"nói dối","fa":"دروغ","examples":[{"de":"Das Buch liegt auf dem Tisch.","en":"The book is lying on the table.","ru":"Книга лежит на столе.","vi":"Cuốn sách ở trên bàn.","fa":"کتاب روی میز است."},{"de":"Die Stadt liegt an einem See.","en":"The city is located by a lake.","ru":"Город расположен у озера.","vi":"Thành phố nằm trên một hồ nước.","fa":"این شهر روی یک دریاچه قرار دارد."}]},{"word":"Das liegt daran, dass …","en":"That's because … (explaining a cause)","ru":"Это связано с тем, что … (объяснение причины)","vi":"Đó là bởi vì…","fa":"به این دلیل که…","examples":[{"de":"Das liegt daran, dass viele Leute umziehen.","en":"That's because many people are moving.","ru":"Это связано с тем, что многие переезжают.","vi":"Điều này là do rất nhiều người di chuyển.","fa":"این به این دلیل است که افراد زیادی جابجا می شوند."}]},{"word":"der Lift","en":"the elevator; the lift","ru":"лифт","vi":"thang máy","fa":"آسانسور","examples":[{"de":"Der Lift ist heute leider kaputt.","en":"The elevator is unfortunately broken today.","ru":"Лифт сегодня, к сожалению, сломан.","vi":"Thật không may hôm nay thang máy bị hỏng.","fa":"متاسفانه آسانسور امروز خراب است."},{"de":"Wir nehmen den Lift bis in den fünften Stock.","en":"We take the elevator up to the fifth floor.","ru":"Мы поедем на лифте до пятого этажа.","vi":"Chúng tôi đi thang máy lên tầng năm.","fa":"با آسانسور به طبقه پنجم می رویم."}]},{"word":"liken","en":"to like a post on a social network","ru":"ставить лайк, лайкать (в соцсети)","vi":"thích","fa":"مانند","examples":[{"de":"Man kann Posts liken, kommentieren und teilen.","en":"You can like, comment on and share posts.","ru":"Постам можно ставить лайки, комментировать их и делиться ими.","vi":"Bạn có thể thích, bình luận và chia sẻ bài viết.","fa":"می توانید پست ها را لایک کنید، نظر بدهید و به اشتراک بگذارید."},{"de":"Ich like meistens nur Fotos von echten Freunden.","en":"I usually only like photos from real friends.","ru":"Обычно я лайкаю только фото настоящих друзей.","vi":"Tôi hầu như chỉ thích những bức ảnh của những người bạn thực sự.","fa":"من بیشتر فقط عکس دوستان واقعی را دوست دارم."},{"de":"Vergiss nicht, das Video zu liken, wenn es dir gefällt.","en":"Don't forget to like the video if you enjoy it.","ru":"Не забудь поставить лайк видео, если оно тебе нравится.","vi":"Đừng quên thích video nếu bạn thích nó.","fa":"فراموش نکنید اگر ویدیو را دوست داشتید لایک کنید."}]},{"word":"der Likör","en":"liqueur","ru":"ликёр","vi":"rượu mùi","fa":"لیکور","examples":[{"de":"Nach dem Essen tranken wir einen süßen Likör.","en":"After the meal we drank a sweet liqueur.","ru":"После еды мы выпили сладкий ликёр.","vi":"Sau bữa tối, chúng tôi uống rượu mùi ngọt ngào.","fa":"بعد از شام یک لیکور شیرین نوشیدیم."},{"de":"Dieser Likör schmeckt nach Kirschen.","en":"This liqueur tastes of cherries.","ru":"Этот ликёр на вкус как вишня.","vi":"Loại rượu mùi này có vị như quả anh đào.","fa":"طعم این لیکور شبیه گیلاس است."},{"de":"Sie stellt ihren Likör jedes Jahr selbst her.","en":"She makes her own liqueur every year.","ru":"Она каждый год делает свой ликёр сама.","vi":"Cô ấy tự làm rượu mùi mỗi năm.","fa":"او هر سال خودش لیکور درست می کند."}]},{"word":"die Limonade","en":"the lemonade; the soft drink","ru":"лимонад","vi":"nước chanh","fa":"لیموناد","examples":[{"de":"An heißen Tagen trinke ich gerne kalte Limonade.","en":"On hot days I like to drink cold lemonade.","ru":"В жаркие дни я люблю пить холодный лимонад.","vi":"Vào những ngày nắng nóng tôi thích uống nước chanh lạnh.","fa":"در روزهای گرم دوست دارم لیموناد سرد بنوشم."},{"de":"Die Kinder bekamen eine Limonade zum Essen.","en":"The children got a lemonade with their meal.","ru":"Дети получили лимонад к еде.","vi":"Bọn trẻ được cho uống nước chanh trong bữa ăn.","fa":"به بچه ها همراه غذا آبلیمو داده شد."}]},{"word":"die Linie","en":"the line","ru":"линия","vi":"dòng","fa":"خط","examples":[{"de":"Ziehe eine gerade Linie mit dem Lineal.","en":"Draw a straight line with the ruler.","ru":"Проведи прямую линию линейкой.","vi":"Vẽ một đường thẳng bằng thước kẻ.","fa":"با خط کش یک خط مستقیم بکشید."},{"de":"Die U-Bahn-Linie 3 fährt zum Hauptbahnhof.","en":"Subway line 3 goes to the main station.","ru":"Линия метро 3 идёт до главного вокзала.","vi":"Tuyến tàu điện ngầm số 3 đi đến ga chính.","fa":"خط 3 مترو به ایستگاه اصلی می رود."}]},{"word":"link","en":"left (attributive); (colloquial) shady, sneaky","ru":"левый; (разг.) хитрый, подлый, нечестный","vi":"liên kết","fa":"پیوند","examples":[{"de":"Heb bitte deine linke Hand.","en":"Please raise your left hand.","ru":"Пожалуйста, поднимите левую руку.","vi":"Hãy giơ tay trái của bạn lên.","fa":"لطفا دست چپ خود را بالا ببرید."},{"de":"Der Schmerz ist im linken Knie.","en":"The pain is in the left knee.","ru":"Боль в левом колене.","vi":"Cơn đau ở đầu gối trái.","fa":"درد در زانوی چپ است."},{"de":"Auf der linken Seite siehst du das Rathaus.","en":"On the left side you can see the town hall.","ru":"С левой стороны видна ратуша.","vi":"Ở bên trái bạn sẽ thấy tòa thị chính.","fa":"در سمت چپ ساختمان شهرداری را خواهید دید."}]},{"word":"links","en":"left","ru":"налево; слева","vi":"trái","fa":"سمت چپ","examples":[{"de":"An der Ampel musst du links abbiegen.","en":"At the traffic light you have to turn left.","ru":"На светофоре тебе нужно повернуть налево.","vi":"Tại đèn giao thông bạn phải rẽ trái.","fa":"در چراغ راهنمایی باید به چپ بپیچید."},{"de":"Das Geschäft ist gleich links neben der Bank.","en":"The shop is right on the left next to the bank.","ru":"Магазин находится слева от банка.","vi":"Cửa hàng nằm ngay bên trái ngân hàng.","fa":"مغازه درست سمت چپ بانک است."}]},{"word":"die Lippe","en":"the lip","ru":"губа","vi":"môi","fa":"لب","examples":[{"de":"Sie hat sich beim Essen auf die Lippe gebissen.","en":"She bit her lip while eating.","ru":"Она прикусила губу во время еды.","vi":"Cô cắn môi khi ăn.","fa":"هنگام غذا خوردن لبش را گاز گرفت."},{"de":"Seine Lippen waren vor Kälte ganz blau.","en":"His lips were completely blue from the cold.","ru":"Его губы совсем посинели от холода.","vi":"Môi anh xanh xao vì lạnh.","fa":"لب هایش از سرما کبود شده بود."}]},{"word":"die Liste","en":"the list","ru":"список","vi":"danh sách","fa":"لیست","examples":[{"de":"Ich habe eine Liste mit allen Einkäufen geschrieben.","en":"I wrote a list of all the groceries.","ru":"Я составил список всех покупок.","vi":"Tôi đã viết một danh sách tất cả các giao dịch mua.","fa":"لیست تمام خریدها را نوشتم."},{"de":"Sein Name steht ganz oben auf der Liste.","en":"His name is at the very top of the list.","ru":"Его имя стоит в самом верху списка.","vi":"Tên anh ấy đứng đầu danh sách.","fa":"نام او در بالای لیست قرار دارد."}]},{"word":"die Literatur","en":"the literature","ru":"литература","vi":"văn học","fa":"ادبیات","examples":[{"de":"Sie interessiert sich sehr für russische Literatur.","en":"She is very interested in Russian literature.","ru":"Она очень интересуется русской литературой.","vi":"Cô ấy rất quan tâm đến văn học Nga.","fa":"او علاقه زیادی به ادبیات روسی دارد."},{"de":"An der Uni studiert er deutsche Literatur.","en":"At university he studies German literature.","ru":"В университете он изучает немецкую литературу.","vi":"Ở trường đại học, anh ấy nghiên cứu văn học Đức.","fa":"در دانشگاه ادبیات آلمانی می خواند."}]},{"word":"loben","en":"to praise","ru":"хвалить","vi":"khen ngợi","fa":"ستایش","examples":[{"de":"Der Lehrer lobte den Schüler für seine gute Arbeit.","en":"The teacher praised the student for his good work.","ru":"Учитель похвалил ученика за хорошую работу.","vi":"Cô giáo khen ngợi học sinh đã làm việc tốt.","fa":"معلم از شاگرد به خاطر کار خوبش تمجید کرد."},{"de":"Meine Eltern loben mich selten.","en":"My parents rarely praise me.","ru":"Мои родители редко меня хвалят.","vi":"Bố mẹ tôi hiếm khi khen ngợi tôi.","fa":"پدر و مادرم به ندرت از من تعریف می کنند."}]},{"word":"das Loch","en":"the hole","ru":"дыра","vi":"cái lỗ","fa":"سوراخ","examples":[{"de":"In meiner Hose ist ein großes Loch.","en":"There's a big hole in my pants.","ru":"В моих брюках большая дыра.","vi":"Có một cái lỗ lớn trên quần của tôi.","fa":"یک سوراخ بزرگ در شلوار من وجود دارد."},{"de":"Der Hund hat ein Loch im Garten gegraben.","en":"The dog dug a hole in the garden.","ru":"Собака вырыла яму в саду.","vi":"Con chó đào một cái lỗ trong vườn.","fa":"سگ در باغچه حفر کرد."}]},{"word":"locker","en":"loose; relaxed","ru":"свободный; расслабленный","vi":"lỏng lẻo","fa":"شل","examples":[{"de":"Die Schraube ist locker und muss festgezogen werden.","en":"The screw is loose and needs to be tightened.","ru":"Винт разболтался, его нужно затянуть.","vi":"Vít bị lỏng và cần phải siết chặt lại.","fa":"پیچ شل است و باید سفت شود."},{"de":"Bleib locker, es wird schon alles gut gehen.","en":"Stay relaxed, everything will turn out fine.","ru":"Расслабься, всё будет хорошо.","vi":"Hãy bình tĩnh, mọi thứ sẽ ổn thôi.","fa":"آرام باش، همه چیز درست خواهد شد."}]},{"word":"der Löffel","en":"the spoon","ru":"ложка","vi":"cái thìa","fa":"قاشق","examples":[{"de":"Sie rührt den Kaffee mit einem Löffel um.","en":"She stirs the coffee with a spoon.","ru":"Она размешивает кофе ложкой.","vi":"Cô ấy khuấy cà phê bằng thìa.","fa":"قهوه را با قاشق هم می‌زند."},{"de":"Kannst du mir bitte einen Löffel für die Suppe geben?","en":"Can you please give me a spoon for the soup?","ru":"Можешь дать мне ложку для супа?","vi":"Bạn có thể vui lòng cho tôi một thìa súp được không?","fa":"میشه لطفا یک قاشق برای سوپ به من بدهید؟"}]},{"word":"die Logik","en":"logic","ru":"логика","vi":"logic","fa":"منطق","examples":[{"de":"Sein Argument folgt einer klaren und strengen Logik.","en":"His argument follows a clear and rigorous logic.","ru":"Его аргумент следует ясной и строгой логике.","vi":"Lập luận của ông tuân theo logic rõ ràng và chặt chẽ.","fa":"استدلال او از منطق روشن و دقیق پیروی می کند."},{"de":"Mit reiner Logik allein lässt sich nicht jedes Problem lösen.","en":"Not every problem can be solved by pure logic alone.","ru":"Одной лишь чистой логикой не решить каждую задачу.","vi":"Không phải mọi vấn đề đều có thể được giải quyết chỉ bằng logic thuần túy.","fa":"هر مشکلی را نمی توان تنها با منطق محض حل کرد."},{"de":"Die Logik deiner Erklärung leuchtet mir nicht ganz ein.","en":"The logic of your explanation does not quite make sense to me.","ru":"Логика твоего объяснения мне не совсем понятна.","vi":"Logic giải thích của bạn không hoàn toàn có ý nghĩa với tôi.","fa":"منطق توضیح شما برای من کاملا منطقی نیست."}]},{"word":"der Lohn","en":"the wage; the pay","ru":"заработная плата","vi":"tiền lương","fa":"دستمزدها","examples":[{"de":"Der Lohn wird am Ende des Monats bezahlt.","en":"The wages are paid at the end of the month.","ru":"Зарплата выплачивается в конце месяца.","vi":"Lương được trả vào cuối tháng.","fa":"دستمزد در پایان ماه پرداخت می شود."},{"de":"Sie bekommt einen guten Lohn für ihre Arbeit.","en":"She gets a good wage for her work.","ru":"Она получает хорошую зарплату за свою работу.","vi":"Cô ấy nhận được một mức lương tốt cho công việc của mình.","fa":"او برای کارش دستمزد خوبی می گیرد."}]},{"word":"lohnen","en":"to be worthwhile (reflexive: sich lohnen)","ru":"стоить того, окупаться (возвр.: sich lohnen)","vi":"đáng giá","fa":"با ارزش","examples":[{"de":"Es lohnt sich, diesen Film anzusehen.","en":"It's worth watching this film.","ru":"Этот фильм стоит посмотреть.","vi":"Bộ phim này rất đáng xem.","fa":"این فیلم ارزش دیدن را دارد."},{"de":"Die Mühe hat sich am Ende gelohnt.","en":"The effort paid off in the end.","ru":"В итоге усилия окупились.","vi":"Nỗ lực cuối cùng đã có giá trị.","fa":"تلاش در نهایت ارزش آن را داشت."},{"de":"Lohnt es sich, das alte Auto zu reparieren?","en":"Is it worth repairing the old car?","ru":"Стоит ли чинить старую машину?","vi":"Có đáng để sửa xe cũ không?","fa":"آیا ارزش تعمیر ماشین قدیمی را دارد؟"}]},{"word":"das Lokal","en":"the restaurant; the pub","ru":"заведение (кафе, ресторан)","vi":"địa phương","fa":"محلی","examples":[{"de":"Wir treffen uns heute Abend in einem gemütlichen Lokal.","en":"We're meeting tonight at a cozy restaurant.","ru":"Мы встречаемся сегодня вечером в уютном заведении.","vi":"Tối nay chúng ta sẽ gặp nhau ở một nhà hàng ấm cúng.","fa":"امروز عصر در یک رستوران دنج همدیگر را ملاقات خواهیم کرد."},{"de":"Das Lokal um die Ecke serviert gutes Essen.","en":"The pub around the corner serves good food.","ru":"Заведение за углом подаёт хорошую еду.","vi":"Nhà hàng quanh góc phục vụ đồ ăn ngon.","fa":"رستورانی که در گوشه کناری است غذاهای خوبی سرو می کند."}]},{"word":"los","en":"loose; off; what's going on","ru":"свободный; что происходит","vi":"đi","fa":"برو","examples":[{"de":"Was ist hier los?","en":"What's going on here?","ru":"Что здесь происходит?","vi":"Chuyện gì đang xảy ra ở đây vậy?","fa":"اینجا چه خبر است؟"},{"de":"Los, wir müssen uns beeilen!","en":"Come on, we have to hurry!","ru":"Давай, нам нужно спешить!","vi":"Đi thôi, chúng ta phải nhanh lên!","fa":"بیا، باید عجله کنیم!"}]},{"word":"löschen","en":"to delete; to extinguish","ru":"удалять; тушить","vi":"xóa","fa":"حذف کنید","examples":[{"de":"Ich habe die Datei aus Versehen gelöscht.","en":"I accidentally deleted the file.","ru":"Я случайно удалил файл.","vi":"Tôi vô tình xóa tập tin.","fa":"من تصادفا فایل رو پاک کردم"},{"de":"Die Feuerwehr konnte das Feuer schnell löschen.","en":"The fire department was able to extinguish the fire quickly.","ru":"Пожарные смогли быстро потушить огонь.","vi":"Lực lượng chữa cháy đã kịp thời dập tắt đám cháy.","fa":"آتش نشانی به سرعت توانست آتش را خاموش کند."}]},{"word":"lösen","en":"to solve","ru":"решать","vi":"giải quyết","fa":"حل کند","examples":[{"de":"Er konnte die Aufgabe nicht lösen.","en":"He couldn't solve the task.","ru":"Он не смог решить задачу.","vi":"Anh ấy không thể giải quyết được vấn đề.","fa":"او نتوانست مشکل را حل کند."},{"de":"Wir müssen dieses Problem gemeinsam lösen.","en":"We have to solve this problem together.","ru":"Нам нужно решить эту проблему вместе.","vi":"Chúng ta phải cùng nhau giải quyết vấn đề này.","fa":"ما باید با هم این مشکل را حل کنیم."}]},{"word":"losfahren","en":"to set off; to depart","ru":"отправляться (в путь)","vi":"lái xe đi","fa":"راندن","examples":[{"de":"Der Bus fährt in fünf Minuten los.","en":"The bus departs in five minutes.","ru":"Автобус отправляется через пять минут.","vi":"Xe buýt khởi hành trong năm phút nữa.","fa":"اتوبوس پنج دقیقه دیگر حرکت می کند."},{"de":"Wir sind früh am Morgen losgefahren.","en":"We set off early in the morning.","ru":"Мы отправились рано утром.","vi":"Chúng tôi rời đi vào sáng sớm.","fa":"صبح زود راه افتادیم."}]},{"word":"loslassen","en":"to let go","ru":"отпускать, расслабляться, освобождаться","vi":"buông ra","fa":"رها کن","examples":[{"de":"Lass mit der nächsten Ausatmung alle Anspannung los.","en":"With the next exhalation, let go of all tension.","ru":"На следующем выдохе отпусти всё напряжение.","vi":"Với lần thở ra tiếp theo, hãy giải phóng mọi căng thẳng.","fa":"با بازدم بعدی تمام تنش ها را رها کنید."},{"de":"Beim Yoga lerne ich, meine Sorgen loszulassen.","en":"In yoga I learn to let go of my worries.","ru":"В йоге я учусь отпускать свои тревоги.","vi":"Với yoga, tôi học cách buông bỏ những lo lắng của mình.","fa":"با یوگا یاد می گیرم که نگرانی هایم را رها کنم."},{"de":"Es fällt mir schwer, am Abend einfach loszulassen.","en":"I find it hard simply to let go in the evening.","ru":"Мне трудно вечером просто отпустить всё.","vi":"Thật khó để tôi có thể buông tay vào buổi tối.","fa":"برای من سخت است که فقط عصر را رها کنم."}]},{"word":"die Lösung","en":"the solution","ru":"решение","vi":"giải pháp","fa":"راه حل","examples":[{"de":"Ich habe endlich eine Lösung für das Problem gefunden.","en":"I finally found a solution to the problem.","ru":"Я наконец нашёл решение проблемы.","vi":"Cuối cùng tôi đã tìm ra giải pháp cho vấn đề.","fa":"بالاخره راه حلی برای مشکل پیدا کردم."},{"de":"Die Lösung dieser Aufgabe war ganz einfach.","en":"The solution to this task was quite simple.","ru":"Решение этой задачи было совсем простым.","vi":"Giải pháp cho nhiệm vụ này rất đơn giản.","fa":"راه حل این کار بسیار ساده بود."}]},{"word":"die Luft","en":"the air","ru":"воздух","vi":"không khí","fa":"هوا","examples":[{"de":"Die Luft in den Bergen ist besonders frisch.","en":"The air in the mountains is especially fresh.","ru":"Воздух в горах особенно свежий.","vi":"Không khí trên núi đặc biệt trong lành.","fa":"هوای کوهستانی به خصوص تازه است."},{"de":"Mach bitte das Fenster auf, ich brauche frische Luft.","en":"Please open the window, I need fresh air.","ru":"Пожалуйста, открой окно, мне нужен свежий воздух.","vi":"Làm ơn mở cửa sổ ra, tôi cần chút không khí trong lành.","fa":"لطفا پنجره را باز کنید، من به هوای تازه نیاز دارم."}]},{"word":"lüften","en":"to air, to ventilate (a room)","ru":"проветривать (помещение)","vi":"thông gió","fa":"تهویه کنید","examples":[{"de":"Morgens lüfte ich immer kurz das Schlafzimmer.","en":"In the morning I always briefly air the bedroom.","ru":"По утрам я всегда ненадолго проветриваю спальню.","vi":"Tôi luôn thông gió phòng ngủ một thời gian ngắn vào buổi sáng.","fa":"من همیشه صبح ها اتاق خواب را به طور مختصر تهویه می کنم."},{"de":"Bitte lüfte die Küche, hier riecht es nach Essen.","en":"Please air the kitchen, it smells of food in here.","ru":"Проветри, пожалуйста, кухню, здесь пахнет едой.","vi":"Làm ơn thông gió ra bếp đi, ở đây có mùi đồ ăn.","fa":"لطفا آشپزخانه را هوا بدهید، اینجا بوی غذا می دهد."},{"de":"Im Winter sollte man trotzdem regelmäßig lüften.","en":"In winter you should still ventilate regularly.","ru":"Зимой всё равно нужно регулярно проветривать.","vi":"Bạn vẫn nên thông gió thường xuyên vào mùa đông.","fa":"هنوز هم باید در زمستان به طور منظم تهویه کنید."}]},{"word":"die Luftverschmutzung","en":"air pollution","ru":"загрязнение воздуха","vi":"ô nhiễm không khí","fa":"آلودگی هوا","examples":[{"de":"Die Luftverschmutzung in Großstädten macht viele Menschen krank.","en":"Air pollution in big cities makes many people ill.","ru":"Загрязнение воздуха в крупных городах делает многих людей больными.","vi":"Ô nhiễm không khí ở các thành phố lớn khiến nhiều người mắc bệnh.","fa":"آلودگی هوا در شهرهای بزرگ بسیاری از مردم را بیمار می کند."},{"de":"Weniger Autoverkehr würde die Luftverschmutzung senken.","en":"Less car traffic would reduce air pollution.","ru":"Меньше автомобильного движения снизило бы загрязнение воздуха.","vi":"Ít xe cộ hơn sẽ làm giảm ô nhiễm không khí.","fa":"تردد خودروهای کمتر باعث کاهش آلودگی هوا می شود."},{"de":"An manchen Tagen ist die Luftverschmutzung besonders schlimm.","en":"On some days the air pollution is particularly bad.","ru":"В отдельные дни загрязнение воздуха особенно сильное.","vi":"Một số ngày tình trạng ô nhiễm không khí đặc biệt tồi tệ.","fa":"بعضی روزها آلودگی هوا به خصوص بد است."}]},{"word":"lügen","en":"to lie","ru":"лгать","vi":"nói dối","fa":"دروغ","examples":[{"de":"Er lügt oft, um Probleme zu vermeiden.","en":"He often lies to avoid problems.","ru":"Он часто лжёт, чтобы избежать проблем.","vi":"Anh ấy thường nói dối để tránh rắc rối.","fa":"او اغلب برای جلوگیری از مشکلات دروغ می گوید."},{"de":"Ich weiß, dass du lügst.","en":"I know that you're lying.","ru":"Я знаю, что ты лжёшь.","vi":"Tôi biết bạn đang nói dối.","fa":"میدونم دروغ میگی"}]},{"word":"die Lust","en":"desire; the mood (to do something)","ru":"желание; охота","vi":"mong muốn","fa":"میل","examples":[{"de":"Ich habe heute keine Lust zu kochen.","en":"I don't feel like cooking today.","ru":"Мне сегодня не хочется готовить.","vi":"Hôm nay tôi không có hứng nấu ăn.","fa":"امروز حوصله آشپزی ندارم"},{"de":"Hast du Lust, ins Kino zu gehen?","en":"Do you feel like going to the cinema?","ru":"Хочешь пойти в кино?","vi":"Bạn có cảm thấy muốn đi xem phim không?","fa":"آیا دوست دارید به سینما بروید؟"}]},{"word":"lustig","en":"funny","ru":"весёлый; забавный","vi":"buồn cười","fa":"خنده دار","examples":[{"de":"Der Film war wirklich sehr lustig.","en":"The movie was really very funny.","ru":"Фильм был действительно очень смешным.","vi":"Bộ phim thực sự rất hài hước.","fa":"فیلم واقعا خیلی خنده دار بود."},{"de":"Er erzählt immer lustige Geschichten.","en":"He always tells funny stories.","ru":"Он всегда рассказывает забавные истории.","vi":"Anh ấy luôn kể những câu chuyện hài hước.","fa":"او همیشه داستان های خنده دار می گوید."}]},{"word":"machbar","en":"doable; feasible","ru":"выполнимый, осуществимый","vi":"khả thi","fa":"قابل اجرا","examples":[{"de":"Der Plan ist machbar.","en":"The plan is doable.","ru":"План выполним.","vi":"Kế hoạch này khả thi.","fa":"طرح قابل اجراست"},{"de":"Halten Sie diese Aufgabe für machbar?","en":"Do you think this task is doable?","ru":"Вы считаете эту задачу выполнимой?","vi":"Bạn có nghĩ rằng nhiệm vụ này là khả thi?","fa":"به نظر شما این کار امکان پذیر است؟"},{"de":"Mit etwas mehr Zeit wäre das durchaus machbar.","en":"With a little more time it would be quite feasible.","ru":"С чуть большим количеством времени это вполне осуществимо.","vi":"Chỉ cần thêm một chút thời gian, điều này sẽ hoàn toàn có thể thực hiện được.","fa":"با کمی زمان بیشتر این امر کاملاً قابل انجام است."}]},{"word":"machen","en":"to make; to do","ru":"делать","vi":"làm","fa":"انجام دهید","examples":[{"de":"Was machst du heute Abend?","en":"What are you doing tonight?","ru":"Что ты делаешь сегодня вечером?","vi":"Tối nay bạn đang làm gì?","fa":"امشب چیکار میکنی؟"},{"de":"Meine Mutter macht das Essen für uns alle.","en":"My mother makes the food for all of us.","ru":"Моя мама готовит еду для всех нас.","vi":"Mẹ tôi làm bữa tối cho tất cả chúng tôi.","fa":"مادرم برای همه ما شام درست می کند."}]},{"word":"das Mädchen","en":"the girl","ru":"девочка","vi":"cô gái","fa":"دختر","examples":[{"de":"Das kleine Mädchen spielt im Garten.","en":"The little girl is playing in the garden.","ru":"Маленькая девочка играет в саду.","vi":"Cô bé đang chơi trong vườn.","fa":"دخترک در باغ بازی می کند."},{"de":"Ein Mädchen aus meiner Klasse zieht bald um.","en":"A girl from my class is moving soon.","ru":"Девочка из моего класса скоро переезжает.","vi":"Một cô gái trong lớp tôi sắp chuyển đi.","fa":"دختری از کلاس من به زودی نقل مکان می کند."}]},{"word":"das Magazin","en":"the magazine","ru":"журнал","vi":"tạp chí","fa":"مجله","examples":[{"de":"Sie liest jede Woche ein neues Magazin.","en":"She reads a new magazine every week.","ru":"Она каждую неделю читает новый журнал.","vi":"Cô ấy đọc một tạp chí mới mỗi tuần.","fa":"او هر هفته یک مجله جدید می خواند."},{"de":"Im Wartezimmer lagen viele bunte Magazine.","en":"There were many colorful magazines in the waiting room.","ru":"В приёмной лежало много красочных журналов.","vi":"Có rất nhiều tạp chí đầy màu sắc trong phòng chờ.","fa":"تعداد زیادی مجلات رنگارنگ در اتاق انتظار بود."}]},{"word":"der Magen","en":"the stomach","ru":"желудок","vi":"dạ dày","fa":"معده","examples":[{"de":"Mir tut der Magen weh.","en":"My stomach hurts.","ru":"У меня болит живот.","vi":"Bụng tôi đau quá.","fa":"شکمم درد میکنه"},{"de":"Auf leeren Magen sollte man keinen Kaffee trinken.","en":"You shouldn't drink coffee on an empty stomach.","ru":"На пустой желудок не стоит пить кофе.","vi":"Bạn không nên uống cà phê khi bụng đói.","fa":"نباید با معده خالی قهوه بنوشید."}]},{"word":"die Magenschmerzen","en":"stomach ache (plural)","ru":"боли в животе (мн. ч.)","vi":"đau bụng","fa":"درد معده","examples":[{"de":"Nach dem fetten Essen hatte ich starke Magenschmerzen.","en":"After the greasy meal I had bad stomach ache.","ru":"После жирной еды у меня сильно заболел живот.","vi":"Sau khi ăn đồ béo, tôi bị đau bụng dữ dội.","fa":"بعد از خوردن غذای چرب معده درد شدیدی داشتم."},{"de":"Bei Magenschmerzen trinke ich gerne einen Tee.","en":"When I have stomach ache I like to drink a tea.","ru":"Когда у меня болит живот, я люблю пить чай.","vi":"Khi tôi bị đau bụng, tôi thích uống trà.","fa":"وقتی معده درد دارم، دوست دارم چای بنوشم."},{"de":"Sie blieb wegen ihrer Magenschmerzen zu Hause.","en":"She stayed at home because of her stomach ache.","ru":"Она осталась дома из-за болей в животе.","vi":"Cô ấy ở nhà vì đau bụng.","fa":"او به دلیل درد معده در خانه ماند."}]},{"word":"mager","en":"lean; skinny","ru":"худой; постный","vi":"nạc","fa":"لاغر","examples":[{"de":"Er isst gerne mageres Fleisch.","en":"He likes to eat lean meat.","ru":"Он любит есть постное мясо.","vi":"Anh ấy thích ăn thịt nạc.","fa":"او دوست دارد گوشت بدون چربی بخورد."},{"de":"Nach der Krankheit war sie sehr mager.","en":"After the illness she was very thin.","ru":"После болезни она была очень худой.","vi":"Sau cơn bệnh, cô ấy rất gầy.","fa":"بعد از بیماری او بسیار لاغر شده بود."}]},{"word":"die Mahlzeit","en":"the meal","ru":"приём пищи; трапеза","vi":"bữa ăn","fa":"غذا","examples":[{"de":"Wir essen drei Mahlzeiten am Tag.","en":"We eat three meals a day.","ru":"Мы едим три раза в день.","vi":"Chúng tôi ăn ba bữa một ngày.","fa":"ما روزی سه وعده غذا می خوریم."},{"de":"Die letzte Mahlzeit war schon vor sechs Stunden.","en":"The last meal was already six hours ago.","ru":"Последний приём пищи был уже шесть часов назад.","vi":"Bữa ăn cuối cùng đã cách đây sáu tiếng.","fa":"آخرین وعده غذایی شش ساعت پیش بود."}]},{"word":"die Mahlzeitenplanung","en":"meal planning","ru":"планирование питания, планирование приёмов пищи","vi":"kế hoạch bữa ăn","fa":"برنامه ریزی وعده های غذایی","examples":[{"de":"Mit guter Mahlzeitenplanung spart man Zeit und Geld.","en":"With good meal planning you save time and money.","ru":"С хорошим планированием питания экономишь время и деньги.","vi":"Lập kế hoạch bữa ăn tốt giúp bạn tiết kiệm thời gian và tiền bạc.","fa":"برنامه ریزی خوب وعده های غذایی باعث صرفه جویی در وقت و هزینه شما می شود."},{"de":"Am Wochenende mache ich immer die Mahlzeitenplanung.","en":"At the weekend I always do the meal planning.","ru":"По выходным я всегда планирую питание.","vi":"Tôi luôn lên kế hoạch cho bữa ăn vào cuối tuần.","fa":"من همیشه در آخر هفته برنامه ریزی غذا انجام می دهم."},{"de":"Die Mahlzeitenplanung hilft, weniger Essen wegzuwerfen.","en":"Meal planning helps to throw away less food.","ru":"Планирование питания помогает меньше выбрасывать еду.","vi":"Lập kế hoạch bữa ăn giúp bạn ít vứt bỏ thức ăn hơn.","fa":"برنامه ریزی غذایی به شما کمک می کند تا غذای کمتری را دور بریزید."}]},{"word":"die Mahnung","en":"the reminder; the warning notice","ru":"напоминание; предупреждение","vi":"lời nhắc nhở","fa":"یادآوری","examples":[{"de":"Ich habe eine Mahnung bekommen, weil ich die Rechnung vergessen habe.","en":"I received a reminder because I forgot the bill.","ru":"Я получил напоминание, потому что забыл про счёт.","vi":"Tôi nhận được lời nhắc vì quên hóa đơn.","fa":"من یک یادآوری دریافت کردم زیرا فاکتور را فراموش کرده بودم."},{"de":"Nach der zweiten Mahnung habe ich sofort bezahlt.","en":"After the second reminder I paid immediately.","ru":"После второго напоминания я сразу заплатил.","vi":"Sau lần nhắc thứ hai tôi đã thanh toán ngay lập tức.","fa":"بعد از یادآوری دوم بلافاصله پرداخت کردم."}]},{"word":"mal","en":"times; once (modal particle)","ru":"раз; -ка (частица)","vi":"lần","fa":"بارها","examples":[{"de":"Kannst du mir mal helfen?","en":"Can you help me for a moment?","ru":"Можешь мне немного помочь?","vi":"Bạn có thể giúp tôi được không?","fa":"می توانید به من کمک کنید؟"},{"de":"Drei mal drei ist neun.","en":"Three times three is nine.","ru":"Трижды три равно девять.","vi":"Ba lần ba là chín.","fa":"سه ضربدر سه می شود نه."}]},{"word":"das Mal","en":"the time (occasion)","ru":"раз (случай)","vi":"thời gian","fa":"زمان","examples":[{"de":"Das war das erste Mal, dass ich Sushi gegessen habe.","en":"That was the first time I ate sushi.","ru":"Это был первый раз, когда я ел суши.","vi":"Đó là lần đầu tiên tôi ăn sushi.","fa":"اولین بار بود که سوشی خوردم."},{"de":"Beim nächsten Mal komme ich früher.","en":"Next time I'll come earlier.","ru":"В следующий раз я приду раньше.","vi":"Lần sau tôi sẽ đến sớm hơn.","fa":"دفعه بعد زودتر میام"}]},{"word":"malen","en":"to paint","ru":"рисовать (красками)","vi":"sơn","fa":"رنگ کردن","examples":[{"de":"Die Kinder malen bunte Bilder.","en":"The children are painting colorful pictures.","ru":"Дети рисуют яркие картины.","vi":"Trẻ vẽ những bức tranh đầy màu sắc.","fa":"بچه ها نقاشی های رنگارنگ می کشند."},{"de":"Sie malt gerne Landschaften in ihrer Freizeit.","en":"She likes to paint landscapes in her free time.","ru":"В свободное время она любит рисовать пейзажи.","vi":"Cô thích vẽ tranh phong cảnh vào thời gian rảnh rỗi.","fa":"او در اوقات فراغت خود از نقاشی مناظر لذت می برد."}]},{"word":"der Maler","en":"painter (artist or decorator)","ru":"художник; маляр","vi":"họa sĩ","fa":"نقاش","examples":[{"de":"Der Maler hat ein wunderschönes Bild gemalt.","en":"The painter painted a beautiful picture.","ru":"Художник написал красивую картину.","vi":"Họa sĩ đã vẽ một bức tranh đẹp.","fa":"نقاش نقاشی زیبایی کشید."},{"de":"Wir haben einen Maler bestellt, der die Wohnung streicht.","en":"We've booked a painter to paint the flat.","ru":"Мы вызвали маляра, чтобы покрасить квартиру.","vi":"Chúng tôi đã thuê một họa sĩ để sơn căn hộ.","fa":"برای رنگ آمیزی آپارتمان یک نقاش استخدام کردیم."},{"de":"Dieser Maler ist im ganzen Land berühmt.","en":"This painter is famous all over the country.","ru":"Этот художник знаменит на всю страну.","vi":"Họa sĩ này nổi tiếng khắp cả nước.","fa":"این نقاش در سراسر کشور شهرت دارد."}]},{"word":"die Malerin","en":"painter (female; artist or decorator)","ru":"художница; маляр (о женщине)","vi":"họa sĩ","fa":"نقاش","examples":[{"de":"Die Malerin stellt ihre Bilder in einer Galerie aus.","en":"The painter is exhibiting her pictures in a gallery.","ru":"Художница выставляет свои картины в галерее.","vi":"Họa sĩ trưng bày những bức tranh của mình trong một phòng trưng bày.","fa":"نقاش تصاویر خود را در یک گالری به نمایش می گذارد."},{"de":"Meine Tante ist eine bekannte Malerin.","en":"My aunt is a well-known painter.","ru":"Моя тётя — известная художница.","vi":"Dì tôi là một họa sĩ nổi tiếng.","fa":"خاله من نقاش سرشناسی است."},{"de":"Die Malerin hat unser Schlafzimmer hellgrün gestrichen.","en":"The painter painted our bedroom light green.","ru":"Маляр покрасила нашу спальню в светло-зелёный цвет.","vi":"Người họa sĩ đã sơn phòng ngủ của chúng tôi màu xanh nhạt.","fa":"نقاش اتاق خواب ما را سبز روشن کرد."}]},{"word":"man","en":"one; you (impersonal)","ru":"безличное местоимение (кто-то, вообще)","vi":"người ta","fa":"آدم؛ شخص","examples":[{"de":"Man kann hier gut parken.","en":"One can park well here.","ru":"Здесь удобно парковаться.","vi":"Bạn có thể đậu xe dễ dàng ở đây.","fa":"می توانید به راحتی اینجا پارک کنید."},{"de":"In Deutschland isst man gerne Brot zum Frühstück.","en":"In Germany, people like to eat bread for breakfast.","ru":"В Германии на завтрак обычно едят хлеб.","vi":"Ở Đức người ta thích ăn bánh mì vào bữa sáng.","fa":"در آلمان مردم دوست دارند برای صبحانه نان بخورند."}]},{"word":"manch-","en":"some; many a","ru":"некоторый","vi":"một số-","fa":"برخی -","examples":[{"de":"Manche Leute mögen keinen Kaffee.","en":"Some people don't like coffee.","ru":"Некоторые люди не любят кофе.","vi":"Một số người không thích cà phê.","fa":"بعضی ها قهوه دوست ندارند."},{"de":"An manchen Tagen regnet es den ganzen Tag.","en":"On some days it rains all day.","ru":"В некоторые дни идёт дождь весь день.","vi":"Có ngày trời mưa cả ngày.","fa":"بعضی روزها تمام روز باران می بارد."}]},{"word":"manchmal","en":"sometimes","ru":"иногда","vi":"đôi khi","fa":"گاهی اوقات","examples":[{"de":"Manchmal gehe ich abends spazieren.","en":"Sometimes I go for a walk in the evening.","ru":"Иногда я гуляю по вечерам.","vi":"Thỉnh thoảng tôi đi dạo vào buổi tối.","fa":"گاهی عصرها به پیاده روی می روم."},{"de":"Sie ruft mich manchmal am Wochenende an.","en":"She sometimes calls me on the weekend.","ru":"Она иногда звонит мне по выходным.","vi":"Thỉnh thoảng cô ấy gọi cho tôi vào cuối tuần.","fa":"او گاهی اوقات آخر هفته ها با من تماس می گیرد."}]},{"word":"der Mangel","en":"the lack; the shortage","ru":"недостаток; нехватка","vi":"sự thiếu sót","fa":"کمبود","examples":[{"de":"In der Stadt herrscht ein Mangel an Wohnungen.","en":"There is a shortage of apartments in the city.","ru":"В городе ощущается нехватка квартир.","vi":"Thành phố đang thiếu nhà ở.","fa":"کمبود مسکن در شهر وجود دارد."},{"de":"Der Mangel an Schlaf macht ihn müde.","en":"The lack of sleep makes him tired.","ru":"Недостаток сна делает его усталым.","vi":"Việc thiếu ngủ khiến anh mệt mỏi.","fa":"کم خوابی او را خسته می کند."}]},{"word":"der Mann","en":"the man; the husband","ru":"мужчина; муж","vi":"người đàn ông","fa":"مرد","examples":[{"de":"Der Mann dort drüben ist mein Nachbar.","en":"The man over there is my neighbor.","ru":"Мужчина вон там — мой сосед.","vi":"Người đàn ông đằng kia là hàng xóm của tôi.","fa":"اون مرد اونجا همسایه منه"},{"de":"Ihr Mann arbeitet als Ingenieur.","en":"Her husband works as an engineer.","ru":"Её муж работает инженером.","vi":"Chồng cô làm kỹ sư.","fa":"شوهرش به عنوان مهندس کار می کند."}]},{"word":"die Mannschaft","en":"the team","ru":"команда","vi":"đội","fa":"تیم","examples":[{"de":"Unsere Mannschaft hat das Spiel gewonnen.","en":"Our team won the game.","ru":"Наша команда выиграла игру.","vi":"Đội của chúng tôi đã thắng trò chơi.","fa":"تیم ما برنده بازی شد."},{"de":"Er spielt seit fünf Jahren in dieser Mannschaft.","en":"He has been playing on this team for five years.","ru":"Он играет в этой команде уже пять лет.","vi":"Anh ấy đã chơi ở đội này được 5 năm.","fa":"او پنج سال است که در این تیم بازی می کند."}]},{"word":"der Mantel","en":"the coat","ru":"пальто","vi":"chiếc áo khoác","fa":"کت","examples":[{"de":"Zieh deinen Mantel an, es ist kalt draußen.","en":"Put on your coat, it's cold outside.","ru":"Надень пальто, на улице холодно.","vi":"Mặc áo khoác vào đi, ngoài trời lạnh lắm.","fa":"کتت را بپوش، بیرون سرد است."},{"de":"Sie hängte ihren Mantel an die Garderobe.","en":"She hung her coat on the coat rack.","ru":"Она повесила пальто на вешалку.","vi":"Cô treo áo khoác lên giá treo áo khoác.","fa":"کتش را روی چوب لباسی آویزان کرد."}]},{"word":"die Mappe","en":"the folder; the briefcase","ru":"папка; портфель","vi":"thư mục","fa":"پوشه","examples":[{"de":"Er trägt alle Dokumente in einer Mappe.","en":"He carries all the documents in a folder.","ru":"Он носит все документы в папке.","vi":"Anh ta mang tất cả tài liệu vào một cặp.","fa":"او تمام اسناد را در یک پوشه حمل می کند."},{"de":"Die Schülerin legte die Hausaufgaben in ihre Mappe.","en":"The student put her homework in her folder.","ru":"Ученица положила домашнее задание в свою папку.","vi":"Học sinh cất bài tập về nhà vào cặp của mình.","fa":"دانش آموز تکالیف را در پوشه خود گذاشت."}]},{"word":"das Märchen","en":"the fairy tale","ru":"сказка","vi":"câu chuyện cổ tích","fa":"افسانه","examples":[{"de":"Meine Oma erzählt mir jeden Abend ein Märchen.","en":"My grandma tells me a fairy tale every evening.","ru":"Моя бабушка каждый вечер рассказывает мне сказку.","vi":"Bà tôi kể cho tôi nghe một câu chuyện cổ tích vào mỗi buổi tối.","fa":"مادربزرگم هر روز عصر یک افسانه برایم تعریف می کند."},{"de":"Das Märchen von Rotkäppchen kennt jedes Kind.","en":"Every child knows the fairy tale of Little Red Riding Hood.","ru":"Сказку о Красной Шапочке знает каждый ребёнок.","vi":"Mọi đứa trẻ đều biết đến câu chuyện cổ tích Cô bé quàng khăn đỏ.","fa":"هر کودکی افسانه کلاه قرمزی را می شناسد."}]},{"word":"die Margarine","en":"the margarine","ru":"маргарин","vi":"bơ thực vật","fa":"مارگارین","examples":[{"de":"Sie streicht Margarine auf das Brot.","en":"She spreads margarine on the bread.","ru":"Она намазывает маргарин на хлеб.","vi":"Cô phết bơ thực vật lên bánh mì.","fa":"او مارگارین را روی نان پخش می کند."},{"de":"Für den Kuchen brauchen wir Margarine statt Butter.","en":"For the cake we need margarine instead of butter.","ru":"Для торта нам нужен маргарин вместо масла.","vi":"Đối với bánh chúng ta cần bơ thực vật thay vì bơ.","fa":"برای کیک به جای کره به مارگارین نیاز داریم."}]},{"word":"die Marille","en":"the apricot","ru":"абрикос","vi":"quả mơ","fa":"زردآلو","examples":[{"de":"Im Sommer kaufen wir frische Marillen am Markt.","en":"In summer we buy fresh apricots at the market.","ru":"Летом мы покупаем свежие абрикосы на рынке.","vi":"Vào mùa hè, chúng tôi mua mơ tươi ở chợ.","fa":"در تابستان زردآلو تازه از بازار می خریم."},{"de":"Aus den Marillen macht meine Oma leckere Marmelade.","en":"My grandma makes delicious jam from the apricots.","ru":"Из абрикосов моя бабушка делает вкусное варенье.","vi":"Bà tôi làm món mứt ngon từ mơ.","fa":"مادربزرگ من از زردآلو مربای خوشمزه درست می کند."}]},{"word":"die Marke","en":"the brand; the stamp","ru":"марка; бренд","vi":"thương hiệu","fa":"نام تجاری","examples":[{"de":"Er kauft immer Kleidung von bekannten Marken.","en":"He always buys clothes from well-known brands.","ru":"Он всегда покупает одежду известных брендов.","vi":"Anh ấy luôn mua quần áo của những thương hiệu nổi tiếng.","fa":"او همیشه از برندهای معروف لباس می خرد."},{"de":"Ich brauche noch eine Marke für den Brief.","en":"I still need a stamp for the letter.","ru":"Мне ещё нужна марка для письма.","vi":"Tôi vẫn cần một con tem cho bức thư.","fa":"من هنوز برای نامه مهر نیاز دارم."}]},{"word":"markieren","en":"to mark","ru":"отмечать; маркировать","vi":"đánh dấu","fa":"علامت گذاری کنید","examples":[{"de":"Bitte markiere die wichtigen Wörter im Text.","en":"Please mark the important words in the text.","ru":"Пожалуйста, отметь важные слова в тексте.","vi":"Hãy đánh dấu những từ quan trọng trong văn bản.","fa":"لطفا کلمات مهم در متن را علامت بزنید."},{"de":"Der Weg im Wald ist mit gelben Zeichen markiert.","en":"The path in the forest is marked with yellow signs.","ru":"Тропа в лесу отмечена жёлтыми знаками.","vi":"Con đường trong rừng được đánh dấu bằng biển báo màu vàng.","fa":"مسیر در جنگل با علائم زرد مشخص شده است."}]},{"word":"der Markt","en":"market","ru":"рынок","vi":"thị trường","fa":"بازار","examples":[{"de":"Am Samstag gehe ich immer auf den Markt, um frisches Gemüse zu kaufen.","en":"On Saturdays I always go to the market to buy fresh vegetables.","ru":"По субботам я всегда хожу на рынок, чтобы купить свежие овощи.","vi":"Vào thứ bảy tôi luôn đi chợ mua rau tươi.","fa":"روز شنبه همیشه برای خرید سبزیجات تازه به بازار می روم."},{"de":"Der Markt für Elektroautos wächst schnell.","en":"The market for electric cars is growing quickly.","ru":"Рынок электромобилей быстро растёт.","vi":"Thị trường ô tô điện đang phát triển nhanh chóng.","fa":"بازار خودروهای الکتریکی به سرعت در حال رشد است."}]},{"word":"die Marmelade","en":"jam","ru":"варенье, джем","vi":"mứt","fa":"مربا","examples":[{"de":"Zum Frühstück esse ich gerne Brot mit Marmelade.","en":"For breakfast I like to eat bread with jam.","ru":"На завтрак я люблю есть хлеб с вареньем.","vi":"Tôi thích ăn bánh mì với mứt vào bữa sáng.","fa":"من دوست دارم صبحانه نان با مربا بخورم."},{"de":"Meine Oma kocht jedes Jahr Marmelade aus Erdbeeren.","en":"My grandma makes jam from strawberries every year.","ru":"Моя бабушка каждый год варит варенье из клубники.","vi":"Bà tôi làm mứt dâu hàng năm.","fa":"مادربزرگ من هر سال مربای توت فرنگی درست می کند."}]},{"word":"der Mars","en":"Mars","ru":"Марс","vi":"sao Hỏa","fa":"the Mars","examples":[{"de":"Der Mars wird oft der rote Planet genannt.","en":"Mars is often called the red planet.","ru":"Марс часто называют красной планетой.","vi":"Sao Hỏa thường được gọi là hành tinh đỏ.","fa":"مریخ اغلب سیاره سرخ نامیده می شود."},{"de":"Forscher hoffen, eines Tages Menschen zum Mars zu schicken.","en":"Researchers hope to send humans to Mars one day.","ru":"Учёные надеются однажды отправить людей на Марс.","vi":"Các nhà nghiên cứu hy vọng một ngày nào đó sẽ đưa con người lên sao Hỏa.","fa":"محققان امیدوارند روزی انسان را به مریخ بفرستند."},{"de":"Auf dem Mars ist es viel kälter als auf der Erde.","en":"On Mars it is much colder than on Earth.","ru":"На Марсе намного холоднее, чем на Земле.","vi":"Trên sao Hỏa lạnh hơn nhiều so với trên Trái đất.","fa":"در مریخ بسیار سردتر از زمین است."}]},{"word":"die Maschine","en":"machine","ru":"машина, станок","vi":"cái máy","fa":"دستگاه","examples":[{"de":"Die Maschine in der Fabrik produziert hundert Teile pro Stunde.","en":"The machine in the factory produces a hundred parts per hour.","ru":"Станок на фабрике производит сто деталей в час.","vi":"Máy móc trong nhà máy sản xuất được hàng trăm bộ phận mỗi giờ.","fa":"دستگاه در کارخانه صد قطعه در ساعت تولید می کند."},{"de":"Diese Waschmaschine ist eine sehr moderne Maschine.","en":"This washing machine is a very modern machine.","ru":"Эта стиральная машина — очень современная техника.","vi":"Máy giặt này là một chiếc máy rất hiện đại.","fa":"این ماشین لباسشویی یک ماشین لباسشویی بسیار مدرن است."}]},{"word":"massieren","en":"to massage","ru":"массировать, делать массаж","vi":"xoa bóp","fa":"ماساژ دادن","examples":[{"de":"Er lässt sich wöchentlich massieren.","en":"He has himself massaged weekly.","ru":"Ему еженедельно делают массаж.","vi":"Anh ấy được mát-xa hàng tuần.","fa":"او هر هفته ماساژ می گیرد."},{"de":"Die Physiotherapeutin massiert mir den Rücken.","en":"The physiotherapist is massaging my back.","ru":"Физиотерапевт массирует мне спину.","vi":"Nhà vật lý trị liệu xoa bóp lưng cho tôi.","fa":"فیزیوتراپیست کمرم را ماساژ می دهد."},{"de":"Könntest du mir kurz die Schultern massieren?","en":"Could you massage my shoulders for a moment?","ru":"Мог бы ты немного помассировать мне плечи?","vi":"Bạn có thể mát-xa vai nhanh cho tôi được không?","fa":"آیا می توانید یک ماساژ سریع شانه به من بدهید؟"}]},{"word":"die Maßnahme","en":"measure, action","ru":"мера, мероприятие","vi":"biện pháp","fa":"اندازه گیری","examples":[{"de":"Die Regierung beschließt neue Maßnahmen gegen den Klimawandel.","en":"The government is deciding on new measures against climate change.","ru":"Правительство принимает новые меры против изменения климата.","vi":"Chính phủ quyết định các biện pháp mới chống lại biến đổi khí hậu.","fa":"دولت در مورد اقدامات جدید علیه تغییرات آب و هوایی تصمیم می گیرد."},{"de":"Ohne strenge Maßnahmen werden die Ziele nicht erreicht.","en":"Without strict measures the targets will not be reached.","ru":"Без строгих мер целей не достичь.","vi":"Nếu không có biện pháp nghiêm ngặt, mục tiêu sẽ không đạt được.","fa":"بدون تدابیر سخت گیرانه، اهداف محقق نخواهد شد."},{"de":"Eine einfache Maßnahme ist, weniger Auto zu fahren.","en":"A simple measure is to drive less.","ru":"Простая мера — меньше ездить на машине.","vi":"Một biện pháp đơn giản là lái xe ít hơn.","fa":"یک اقدام ساده این است که کمتر رانندگی کنید."}]},{"word":"das Material","en":"material","ru":"материал","vi":"vật liệu","fa":"مواد","examples":[{"de":"Für das Regal brauchen wir Holz als Material.","en":"For the shelf we need wood as material.","ru":"Для полки нам нужно дерево в качестве материала.","vi":"Đối với kệ chúng ta cần gỗ làm vật liệu.","fa":"برای قفسه به چوب به عنوان متریال نیاز داریم."},{"de":"Der Lehrer verteilt das Material für den Kurs.","en":"The teacher hands out the material for the course.","ru":"Преподаватель раздаёт материал для курса.","vi":"Giáo viên phát tài liệu cho khóa học.","fa":"معلم مطالب دوره را توزیع می کند."}]},{"word":"die Matura","en":"school-leaving exam (Abitur, in Austria/Switzerland)","ru":"экзамен на аттестат зрелости (аналог ЕГЭ/Abitur в Австрии и Швейцарии)","vi":"kỳ thi tốt nghiệp trung học","fa":"امتحان نهایی دبیرستان","examples":[{"de":"Nach der Matura möchte sie an der Universität studieren.","en":"After her school-leaving exam, she wants to study at university.","ru":"После сдачи экзамена на аттестат зрелости она хочет учиться в университете.","vi":"Sau khi tốt nghiệp cấp 3, cô muốn học lên đại học.","fa":"پس از فارغ التحصیلی از دبیرستان، او دوست دارد در دانشگاه تحصیل کند."},{"de":"Er hat die Matura mit sehr guten Noten bestanden.","en":"He passed his school-leaving exam with very good grades.","ru":"Он сдал выпускной экзамен с очень хорошими оценками.","vi":"Anh ấy đã đậu bằng tốt nghiệp trung học với điểm số rất tốt.","fa":"دیپلم دبیرستان را با نمرات بسیار خوب گذراند."}]},{"word":"die Mauer","en":"wall","ru":"стена","vi":"bức tường","fa":"دیوار","examples":[{"de":"Um den Garten steht eine hohe Mauer.","en":"There is a high wall around the garden.","ru":"Вокруг сада стоит высокая стена.","vi":"Xung quanh vườn có tường cao.","fa":"اطراف باغ دیوار بلندی است."},{"de":"Die Berliner Mauer fiel im Jahr 1989.","en":"The Berlin Wall fell in 1989.","ru":"Берлинская стена пала в 1989 году.","vi":"Bức tường Berlin sụp đổ năm 1989.","fa":"دیوار برلین در سال 1989 فرو ریخت."}]},{"word":"der Mauerfall","en":"fall of the (Berlin) Wall","ru":"падение (Берлинской) стены","vi":"sự sụp đổ của bức tường","fa":"سقوط دیوار","examples":[{"de":"Der Mauerfall fand im November 1989 statt.","en":"The fall of the Wall took place in November 1989.","ru":"Падение стены произошло в ноябре 1989 года.","vi":"Sự sụp đổ của Bức tường Berlin diễn ra vào tháng 11 năm 1989.","fa":"فروپاشی دیوار برلین در نوامبر 1989 اتفاق افتاد."},{"de":"Viele Menschen weinten vor Freude beim Mauerfall.","en":"Many people cried with joy at the fall of the Wall.","ru":"Многие плакали от радости при падении стены.","vi":"Nhiều người đã khóc vì vui mừng khi Bức tường Berlin sụp đổ.","fa":"وقتی دیوار برلین فرو ریخت، بسیاری از مردم از خوشحالی گریه کردند."},{"de":"Nach dem Mauerfall wurde Deutschland wiedervereinigt.","en":"After the fall of the Wall Germany was reunified.","ru":"После падения стены Германия воссоединилась.","vi":"Sau khi Bức tường Berlin sụp đổ, nước Đức được thống nhất.","fa":"پس از فروپاشی دیوار برلین، آلمان دوباره متحد شد."}]},{"word":"maximal","en":"maximum; at most","ru":"максимальный; максимум","vi":"tối đa","fa":"حداکثر","examples":[{"de":"Der Aufzug darf maximal acht Personen tragen.","en":"The elevator may carry a maximum of eight people.","ru":"Лифт может перевозить максимум восемь человек.","vi":"Thang máy có thể chở tối đa tám người.","fa":"این آسانسور حداکثر می تواند هشت نفر را حمل کند."},{"de":"Die Reise dauert maximal drei Stunden.","en":"The trip takes at most three hours.","ru":"Поездка длится максимум три часа.","vi":"Cuộc hành trình mất tối đa ba giờ.","fa":"سفر حداکثر سه ساعت طول می کشد."}]},{"word":"der Mechaniker","en":"mechanic","ru":"механик","vi":"thợ cơ khí","fa":"مکانیک","examples":[{"de":"Der Mechaniker repariert mein Auto in der Werkstatt.","en":"The mechanic is repairing my car in the workshop.","ru":"Механик ремонтирует мою машину в мастерской.","vi":"Người thợ sửa xe của tôi ở xưởng.","fa":"مکانیک ماشین من را در کارگاه تعمیر می کند."},{"de":"Mein Bruder arbeitet als Mechaniker bei einer Autofirma.","en":"My brother works as a mechanic at a car company.","ru":"Мой брат работает механиком в автомобильной компании.","vi":"Anh trai tôi làm thợ cơ khí ở một công ty ô tô.","fa":"برادرم به عنوان مکانیک در یک شرکت خودروسازی کار می کند."}]},{"word":"die Mechanikerin","en":"mechanic (female)","ru":"механик, автослесарь (женщина)","vi":"thợ cơ khí","fa":"مکانیک","examples":[{"de":"Die Mechanikerin wechselt gerade die Reifen.","en":"The mechanic is just changing the tyres.","ru":"Механик как раз меняет шины.","vi":"Người thợ máy đang thay lốp.","fa":"مکانیک داره لاستیک ها رو عوض میکنه"},{"de":"Sie ist die beste Mechanikerin in der Werkstatt.","en":"She is the best mechanic in the garage.","ru":"Она лучший механик в мастерской.","vi":"Cô ấy là thợ cơ khí giỏi nhất trong xưởng.","fa":"او بهترین مکانیک کارگاه است."},{"de":"Die Mechanikerin erklärte mir das Problem genau.","en":"The mechanic explained the problem to me in detail.","ru":"Механик подробно объяснила мне проблему.","vi":"Người thợ máy đã giải thích chi tiết vấn đề cho tôi.","fa":"مکانیک مشکل را به طور کامل برای من توضیح داد."}]},{"word":"die Medaille","en":"medal","ru":"медаль","vi":"huy chương","fa":"مدال","examples":[{"de":"Sie gewann bei den Spielen eine goldene Medaille.","en":"She won a gold medal at the games.","ru":"Она выиграла золотую медаль на играх.","vi":"Cô đã giành được huy chương vàng tại các trò chơi.","fa":"او در این بازی ها مدال طلا گرفت."},{"de":"Der Sportler zeigte stolz seine Medaille.","en":"The athlete proudly showed his medal.","ru":"Спортсмен гордо показал свою медаль.","vi":"Vận động viên tự hào khoe huy chương của mình.","fa":"این ورزشکار با افتخار مدال خود را نشان داد."},{"de":"Für den dritten Platz gibt es eine bronzene Medaille.","en":"For third place there is a bronze medal.","ru":"За третье место дают бронзовую медаль.","vi":"Có huy chương đồng cho vị trí thứ ba.","fa":"یک مدال برنز برای مقام سوم وجود دارد."}]},{"word":"die Mediathek","en":"media library, on-demand media archive","ru":"медиатека, онлайн-архив передач","vi":"thư viện phương tiện truyền thông","fa":"کتابخانه رسانه","examples":[{"de":"Die Sendung kannst du in der Mediathek nachschauen.","en":"You can watch the programme afterwards in the media library.","ru":"Передачу можно посмотреть потом в медиатеке.","vi":"Bạn có thể xem chương trình trong thư viện phương tiện.","fa":"می توانید این نمایش را در کتابخانه رسانه تماشا کنید."},{"de":"In der Mediathek der Stadt kann man Filme ausleihen.","en":"In the city's media library you can borrow films.","ru":"В городской медиатеке можно брать фильмы.","vi":"Bạn có thể thuê phim trong thư viện phương tiện của thành phố.","fa":"شما می توانید فیلم ها را در کتابخانه رسانه شهر کرایه کنید."},{"de":"Diese Folge ist nur eine Woche in der Mediathek verfügbar.","en":"This episode is only available in the media library for a week.","ru":"Эта серия доступна в медиатеке только неделю.","vi":"Tập này chỉ có sẵn trong thư viện phương tiện trong một tuần.","fa":"این قسمت فقط به مدت یک هفته در کتابخانه رسانه موجود است."}]},{"word":"die Medien","en":"media","ru":"СМИ, медиа","vi":"phương tiện truyền thông","fa":"رسانه ها","examples":[{"de":"Die Medien berichten heute viel über die Wahl.","en":"The media are reporting a lot about the election today.","ru":"СМИ сегодня много пишут о выборах.","vi":"Các phương tiện truyền thông đang đưa tin rất nhiều về cuộc bầu cử ngày hôm nay.","fa":"رسانه ها امروز اخبار زیادی درباره انتخابات دارند."},{"de":"Soziale Medien spielen im Alltag junger Leute eine große Rolle.","en":"Social media play a big role in young people's everyday lives.","ru":"Социальные сети играют большую роль в повседневной жизни молодёжи.","vi":"Phương tiện truyền thông xã hội đóng một vai trò lớn trong cuộc sống hàng ngày của giới trẻ.","fa":"رسانه های اجتماعی نقش مهمی در زندگی روزمره جوانان ایفا می کنند."}]},{"word":"das Medikament","en":"medicine (medication)","ru":"лекарство","vi":"thuốc","fa":"دارو","examples":[{"de":"Der Arzt hat mir ein neues Medikament verschrieben.","en":"The doctor prescribed me a new medicine.","ru":"Врач прописал мне новое лекарство.","vi":"Bác sĩ kê cho tôi một loại thuốc mới.","fa":"دکتر برایم داروی جدیدی تجویز کرد."},{"de":"Du musst das Medikament dreimal am Tag nehmen.","en":"You have to take the medicine three times a day.","ru":"Тебе нужно принимать лекарство три раза в день.","vi":"Bạn phải uống thuốc ba lần một ngày.","fa":"شما باید دارو را سه بار در روز مصرف کنید."}]},{"word":"die Meditation","en":"meditation","ru":"медитация","vi":"thiền định","fa":"مدیتیشن","examples":[{"de":"Nach dem Yoga folgt oft eine kurze Meditation.","en":"After yoga there is often a short meditation.","ru":"После йоги часто следует короткая медитация.","vi":"Yoga thường được theo sau bởi một bài thiền ngắn.","fa":"یوگا اغلب با یک مراقبه کوتاه دنبال می شود."},{"de":"Während der Meditation schließt du die Augen.","en":"During meditation you close your eyes.","ru":"Во время медитации ты закрываешь глаза.","vi":"Trong lúc thiền bạn nhắm mắt lại.","fa":"در طول مدیتیشن چشمان خود را می بندید."},{"de":"Tägliche Meditation kann den Geist beruhigen.","en":"Daily meditation can calm the mind.","ru":"Ежедневная медитация может успокоить ум.","vi":"Thiền định hàng ngày có thể làm dịu tâm trí.","fa":"مدیتیشن روزانه می تواند ذهن را آرام کند."}]},{"word":"meditieren","en":"to meditate","ru":"медитировать","vi":"thiền định","fa":"مدیتیشن","examples":[{"de":"Ich meditiere jeden Morgen vor dem Frühstück.","en":"I meditate every morning before breakfast.","ru":"Я медитирую каждое утро перед завтраком.","vi":"Tôi thiền mỗi sáng trước khi ăn sáng.","fa":"من هر روز صبح قبل از صبحانه مدیتیشن می کنم."},{"de":"Wer regelmäßig meditiert, schläft oft besser.","en":"People who meditate regularly often sleep better.","ru":"Кто регулярно медитирует, часто лучше спит.","vi":"Những người thiền thường xuyên thường ngủ ngon hơn.","fa":"کسانی که به طور منظم مدیتیشن می کنند اغلب خواب بهتری دارند."},{"de":"Versuche, eine Woche lang täglich zu meditieren.","en":"Try to meditate every day for a week.","ru":"Попробуй медитировать каждый день в течение недели.","vi":"Hãy thử thiền hàng ngày trong một tuần.","fa":"سعی کنید روزانه به مدت یک هفته مدیتیشن کنید."}]},{"word":"das Medium","en":"medium","ru":"средство информации, медиа (ед. ч.); носитель","vi":"phương tiện","fa":"رسانه","examples":[{"de":"Das Fernsehen ist ein wichtiges Medium.","en":"Television is an important medium.","ru":"Телевидение — важное средство информации.","vi":"Truyền hình là một phương tiện quan trọng.","fa":"تلویزیون یک رسانه مهم است."},{"de":"Welches Medium nutzt du am meisten?","en":"Which medium do you use the most?","ru":"Каким медиа ты пользуешься чаще всего?","vi":"Bạn sử dụng phương tiện nào nhiều nhất?","fa":"از کدام رسانه بیشتر استفاده می کنید؟"},{"de":"Das Internet ist ein sehr schnelles Medium.","en":"The internet is a very fast medium.","ru":"Интернет — очень быстрое средство информации.","vi":"Internet là một phương tiện rất nhanh.","fa":"اینترنت یک رسانه بسیار سریع است."}]},{"word":"die Medizin","en":"medicine (the field/science; also medication)","ru":"медицина (также лекарство)","vi":"thuốc","fa":"دارو","examples":[{"de":"Sie studiert Medizin, um Ärztin zu werden.","en":"She is studying medicine to become a doctor.","ru":"Она изучает медицину, чтобы стать врачом.","vi":"Cô ấy đang học y khoa để trở thành bác sĩ.","fa":"او در حال تحصیل پزشکی است تا دکتر شود."},{"de":"Die moderne Medizin hat viele Krankheiten heilbar gemacht.","en":"Modern medicine has made many diseases curable.","ru":"Современная медицина сделала многие болезни излечимыми.","vi":"Y học hiện đại đã chữa được nhiều bệnh.","fa":"طب مدرن بسیاری از بیماری ها را قابل درمان کرده است."}]},{"word":"das Meer","en":"sea","ru":"море","vi":"biển","fa":"دریا","examples":[{"de":"Im Sommer fahren wir jedes Jahr ans Meer.","en":"Every summer we go to the sea.","ru":"Каждое лето мы ездим на море.","vi":"Mùa hè nào chúng tôi cũng đi biển.","fa":"هر تابستان در تابستان به دریا می رویم."},{"de":"Das Meer war heute ruhig und blau.","en":"The sea was calm and blue today.","ru":"Море сегодня было спокойным и синим.","vi":"Biển hôm nay lặng và trong xanh.","fa":"دریا امروز آرام و آبی بود."}]},{"word":"das Mehl","en":"flour","ru":"мука","vi":"bột mì","fa":"آرد","examples":[{"de":"Für den Kuchen brauchst du 500 Gramm Mehl.","en":"For the cake you need 500 grams of flour.","ru":"Для торта тебе нужно 500 граммов муки.","vi":"Đối với bánh bạn cần 500 gram bột mì.","fa":"برای کیک به 500 گرم آرد نیاز دارید."},{"de":"Sie kauft Mehl, um Brot zu backen.","en":"She buys flour to bake bread.","ru":"Она покупает муку, чтобы испечь хлеб.","vi":"Cô ấy mua bột mì để nướng bánh mì.","fa":"آرد می خرد تا نان بپزد."}]},{"word":"mehr (siehe auch viel)","en":"more","ru":"больше","vi":"hơn (xem thêm rất nhiều)","fa":"بیشتر (بسیار را نیز ببینید)","examples":[{"de":"Ich brauche mehr Zeit für die Aufgabe.","en":"I need more time for the task.","ru":"Мне нужно больше времени для этого задания.","vi":"Tôi cần thêm thời gian cho nhiệm vụ.","fa":"برای کار به زمان بیشتری نیاز دارم."},{"de":"Er verdient jetzt mehr als früher.","en":"He earns more now than before.","ru":"Сейчас он зарабатывает больше, чем раньше.","vi":"Bây giờ anh ấy kiếm được nhiều tiền hơn trước.","fa":"او الان بیشتر از قبل درآمد دارد."}]},{"word":"mehrere","en":"several, a number of","ru":"несколько, ряд","vi":"một số","fa":"چندین","examples":[{"de":"Ich habe mehrere Bücher zu diesem Thema gelesen.","en":"I have read several books on this subject.","ru":"Я прочитал несколько книг на эту тему.","vi":"Tôi đã đọc một số cuốn sách về chủ đề này.","fa":"من چندین کتاب در این زمینه خوانده ام."},{"de":"Es gibt mehrere Gründe für meine Entscheidung.","en":"There are several reasons for my decision.","ru":"Есть несколько причин для моего решения.","vi":"Có một số lý do cho quyết định của tôi.","fa":"دلایل مختلفی برای تصمیم من وجود دارد."},{"de":"Wir haben mehrere Tage auf eine Antwort gewartet.","en":"We waited several days for an answer.","ru":"Мы ждали ответа несколько дней.","vi":"Chúng tôi đã đợi vài ngày để có câu trả lời.","fa":"چندین روز منتظر جواب بودیم."}]},{"word":"die Mehrheit","en":"majority","ru":"большинство","vi":"đa số","fa":"اکثریت","examples":[{"de":"Die Mehrheit der Schüler war mit dem Vorschlag einverstanden.","en":"The majority of the students agreed with the proposal.","ru":"Большинство учеников согласились с предложением.","vi":"Đa số sinh viên đồng ý với đề xuất này.","fa":"اکثریت دانشجویان با این پیشنهاد موافقت کردند."},{"de":"Bei der Wahl bekam die Partei die Mehrheit der Stimmen.","en":"In the election, the party got the majority of the votes.","ru":"На выборах партия получила большинство голосов.","vi":"Đảng đã nhận được đa số phiếu trong cuộc bầu cử.","fa":"این حزب اکثریت آرا را در انتخابات به دست آورد."}]},{"word":"die Mehrheitsentscheidung","en":"majority decision","ru":"решение большинства","vi":"quyết định đa số","fa":"تصمیم اکثریت","examples":[{"de":"Es war eine Mehrheitsentscheidung.","en":"It was a majority decision.","ru":"Это было решение большинства.","vi":"Đó là một quyết định đa số.","fa":"این تصمیم اکثریت بود."},{"de":"Die Mehrheitsentscheidung gilt für alle.","en":"The majority decision applies to everyone.","ru":"Решение большинства действует для всех.","vi":"Quyết định của đa số áp dụng cho tất cả mọi người.","fa":"تصمیم اکثریت برای همه اعمال می شود."},{"de":"Wir akzeptieren die Mehrheitsentscheidung.","en":"We accept the majority decision.","ru":"Мы принимаем решение большинства.","vi":"Chúng tôi chấp nhận quyết định của đa số.","fa":"ما تصمیم اکثریت را می پذیریم."}]},{"word":"der Mehrwegbehälter","en":"reusable container","ru":"многоразовый контейнер (тара)","vi":"thùng chứa có thể tái sử dụng","fa":"ظرف قابل استفاده مجدد","examples":[{"de":"Im Supermarkt kann man Essen in einem Mehrwegbehälter kaufen.","en":"In the supermarket you can buy food in a reusable container.","ru":"В супермаркете можно купить еду в многоразовом контейнере.","vi":"Trong siêu thị, bạn có thể mua thực phẩm đựng trong hộp đựng có thể tái sử dụng.","fa":"در سوپرمارکت می توانید مواد غذایی را در یک ظرف قابل استفاده مجدد بخرید."},{"de":"Ein Mehrwegbehälter spart viel Verpackungsmüll.","en":"A reusable container saves a lot of packaging waste.","ru":"Многоразовый контейнер экономит много упаковочного мусора.","vi":"Hộp đựng có thể tái sử dụng giúp tiết kiệm rất nhiều rác thải đóng gói.","fa":"ظروف قابل استفاده مجدد، مقدار زیادی از زباله های بسته بندی را ذخیره می کند."},{"de":"Sie bringt immer ihren eigenen Mehrwegbehälter mit.","en":"She always brings her own reusable container.","ru":"Она всегда приносит с собой свой многоразовый контейнер.","vi":"Cô ấy luôn mang theo hộp đựng có thể tái sử dụng của riêng mình.","fa":"او همیشه ظرف قابل استفاده مجدد خود را می آورد."}]},{"word":"die Mehrwegflasche","en":"reusable bottle","ru":"многоразовая бутылка","vi":"chai có thể tái sử dụng","fa":"بطری قابل استفاده مجدد","examples":[{"de":"Eine Mehrwegflasche kann man viele Male benutzen.","en":"A reusable bottle can be used many times.","ru":"Многоразовую бутылку можно использовать много раз.","vi":"Một chai tái sử dụng có thể được sử dụng nhiều lần.","fa":"یک بطری قابل استفاده مجدد را می توان بارها استفاده کرد."},{"de":"Kauf lieber Wasser in der Mehrwegflasche.","en":"Better to buy water in a reusable bottle.","ru":"Лучше покупай воду в многоразовой бутылке.","vi":"Tốt hơn hết bạn nên mua nước đựng trong chai có thể tái sử dụng.","fa":"بهتر است آب را در یک بطری قابل استفاده مجدد بخرید."},{"de":"Die Mehrwegflasche ist umweltfreundlicher als die Einwegflasche.","en":"The reusable bottle is more environmentally friendly than the single-use one.","ru":"Многоразовая бутылка экологичнее одноразовой.","vi":"Chai tái sử dụng thân thiện với môi trường hơn chai dùng một lần.","fa":"بطری قابل استفاده مجدد نسبت به بطری یکبار مصرف سازگارتر با محیط زیست است."}]},{"word":"die Mehrwertsteuer","en":"value-added tax (VAT)","ru":"налог на добавленную стоимость (НДС)","vi":"thuế GTGT","fa":"مالیات بر ارزش افزوده","examples":[{"de":"Die Mehrwertsteuer in Deutschland beträgt normalerweise 19 Prozent.","en":"VAT in Germany is normally 19 percent.","ru":"НДС в Германии обычно составляет 19 процентов.","vi":"VAT ở Đức thường là 19%.","fa":"مالیات بر ارزش افزوده در آلمان به طور معمول 19 درصد است."},{"de":"Der Preis auf dem Etikett enthält schon die Mehrwertsteuer.","en":"The price on the label already includes VAT.","ru":"Цена на ценнике уже включает НДС.","vi":"Giá trên nhãn đã bao gồm VAT.","fa":"قیمت روی برچسب قبلاً شامل مالیات بر ارزش افزوده است."}]},{"word":"meinen","en":"to think; to mean","ru":"думать, полагать; иметь в виду","vi":"nghĩa là","fa":"معنی","examples":[{"de":"Ich meine, dass wir früher losfahren sollten.","en":"I think we should leave earlier.","ru":"Я думаю, что нам следует выехать раньше.","vi":"Tôi nghĩ chúng ta nên rời đi sớm hơn.","fa":"فکر کنم زودتر بریم"},{"de":"Was meinst du mit diesem Satz?","en":"What do you mean by this sentence?","ru":"Что ты имеешь в виду под этим предложением?","vi":"Bạn có ý gì qua câu này?","fa":"منظور شما از این جمله چیست؟"}]},{"word":"meiner","en":"mine; of mine (possessive)","ru":"мой (притяжательное местоимение)","vi":"của tôi","fa":"مال من","examples":[{"de":"Das ist nicht dein Stuhl, das ist meiner.","en":"That isn't your chair, it's mine.","ru":"Это не твой стул, а мой.","vi":"Đây không phải là ghế của bạn, đây là của tôi.","fa":"این صندلی تو نیست، این مال من است."},{"de":"Dein Auto ist neuer als meiner.","en":"Your car is newer than mine.","ru":"Твоя машина новее моей.","vi":"Xe của bạn mới hơn của tôi.","fa":"ماشین شما از من جدیدتره"},{"de":"Sie ist eine gute Freundin meiner Schwester.","en":"She is a good friend of my sister's.","ru":"Она хорошая подруга моей сестры.","vi":"Cô ấy là một người bạn tốt của chị tôi.","fa":"او دوست خوب خواهر من است."}]},{"word":"Meiner Meinung nach …","en":"In my opinion … (stating an opinion)","ru":"По моему мнению … (выражение мнения)","vi":"Theo ý kiến của tôi…","fa":"به نظر من…","examples":[{"de":"Meiner Meinung nach sollte man mehr Fahrrad fahren.","en":"In my opinion, people should cycle more.","ru":"По моему мнению, людям стоит больше ездить на велосипеде.","vi":"Theo tôi bạn nên đi xe đạp nhiều hơn.","fa":"به نظر من شما باید بیشتر دوچرخه سواری کنید."}]},{"word":"meinetwegen","en":"because of me; as far as I'm concerned (fine by me)","ru":"из-за меня; ладно, я не против","vi":"vì lợi ích của tôi","fa":"به خاطر من","examples":[{"de":"Ihr müsst nicht meinetwegen warten.","en":"You don't have to wait because of me.","ru":"Вам не нужно ждать из-за меня.","vi":"Bạn không cần phải đợi tôi.","fa":"لازم نیست منتظر من باشی"},{"de":"Meinetwegen können wir auch ins Kino gehen.","en":"As far as I'm concerned, we can also go to the cinema.","ru":"Что касается меня, мы можем пойти и в кино.","vi":"Theo như tôi được biết, chúng ta cũng có thể đi xem phim.","fa":"تا جایی که من می توانم به سینما هم برویم."}]},{"word":"die Meinung","en":"opinion","ru":"мнение","vi":"ý kiến","fa":"نظر","examples":[{"de":"Meiner Meinung nach ist dieser Film sehr gut.","en":"In my opinion, this film is very good.","ru":"По моему мнению, этот фильм очень хороший.","vi":"Theo tôi bộ phim này rất hay.","fa":"به نظر من این فیلم خیلی خوبه"},{"de":"Wir haben unterschiedliche Meinungen zu diesem Thema.","en":"We have different opinions on this topic.","ru":"У нас разные мнения по этому вопросу.","vi":"Chúng tôi có ý kiến ​​​​khác nhau về chủ đề này.","fa":"ما نظرات مختلفی در مورد این موضوع داریم."}]},{"word":"meist-","en":"most (prefix/stem, e.g. 'die meisten' = most people/things)","ru":"большинство (основа, напр. 'die meisten' — большинство)","vi":"chủ yếu-","fa":"بیشتر-","examples":[{"de":"Die meisten Leute in meiner Klasse kommen aus der Stadt.","en":"Most of the people in my class come from the city.","ru":"Большинство людей в моём классе из города.","vi":"Hầu hết mọi người trong lớp tôi đều đến từ thành phố.","fa":"اکثر افراد کلاس من اهل شهر هستند."},{"de":"Die meisten Geschäfte schließen sonntags.","en":"Most shops close on Sundays.","ru":"Большинство магазинов закрыты по воскресеньям.","vi":"Hầu hết các cửa hàng đóng cửa vào ngày chủ nhật.","fa":"اکثر مغازه ها یکشنبه ها تعطیل می شوند."}]},{"word":"meist(ens)","en":"mostly; usually","ru":"обычно, большей частью","vi":"chủ yếu","fa":"بیشتر","examples":[{"de":"Ich fahre meistens mit dem Fahrrad zur Arbeit.","en":"I usually go to work by bike.","ru":"Обычно я езжу на работу на велосипеде.","vi":"Tôi thường đi xe đạp đi làm.","fa":"من معمولاً با دوچرخه به سر کار می روم."},{"de":"Am Wochenende bleiben wir meist zu Hause.","en":"On weekends we mostly stay at home.","ru":"По выходным мы обычно остаёмся дома.","vi":"Chúng tôi thường ở nhà vào cuối tuần.","fa":"ما معمولا آخر هفته ها در خانه می مانیم."}]},{"word":"der Meister","en":"master (craftsman); champion","ru":"мастер; чемпион","vi":"bậc thầy; nhà vô địch","fa":"استاد","examples":[{"de":"Mein Onkel ist Meister in seinem Handwerk.","en":"My uncle is a master of his craft.","ru":"Мой дядя — мастер своего ремесла.","vi":"Chú tôi là bậc thầy trong nghề của mình.","fa":"دایی من در کار خود استاد است."},{"de":"Die Mannschaft wurde dieses Jahr deutscher Meister.","en":"The team became German champion this year.","ru":"В этом году команда стала чемпионом Германии.","vi":"Đội đã trở thành nhà vô địch Đức năm nay.","fa":"این تیم امسال قهرمان آلمان شد."}]},{"word":"meistern","en":"to master, to cope with","ru":"справляться, овладевать, преодолевать","vi":"bậc thầy","fa":"استاد","examples":[{"de":"Sie hat die schwierige Situation souverän gemeistert.","en":"She mastered the difficult situation with confidence.","ru":"Она уверенно справилась со сложной ситуацией.","vi":"Cô tự tin làm chủ hoàn cảnh khó khăn.","fa":"او با اطمینان بر شرایط دشوار تسلط یافت."},{"de":"Mit Übung kann man jede Herausforderung meistern.","en":"With practice you can master any challenge.","ru":"С практикой можно осилить любой вызов.","vi":"Với sự luyện tập, bạn có thể vượt qua mọi thử thách.","fa":"با تمرین می توانید بر هر چالشی غلبه کنید."},{"de":"Wir mussten viele Probleme meistern, bevor das Projekt fertig war.","en":"We had to overcome many problems before the project was finished.","ru":"Нам пришлось преодолеть много проблем, прежде чем проект был завершён.","vi":"Chúng tôi đã phải khắc phục nhiều vấn đề trước khi dự án hoàn thành.","fa":"قبل از اینکه پروژه به پایان برسد باید بر مشکلات زیادی غلبه می کردیم."}]},{"word":"melden","en":"to report","ru":"сообщать, заявлять","vi":"báo cáo","fa":"گزارش دهید","examples":[{"de":"Ich möchte einen Diebstahl bei der Polizei melden.","en":"I would like to report a theft to the police.","ru":"Я хочу заявить в полицию о краже.","vi":"Tôi muốn báo cảnh sát về một vụ trộm.","fa":"من می خواهم یک سرقت را به پلیس گزارش کنم."},{"de":"Der Lehrer meldete den Vorfall der Schulleitung.","en":"The teacher reported the incident to the school management.","ru":"Учитель сообщил о происшествии руководству школы.","vi":"Cô giáo đã báo cáo sự việc với ban giám hiệu nhà trường.","fa":"معلم ماجرا را به مدیریت مدرسه گزارش داد."}]},{"word":"die Meldung","en":"report; notification; news item","ru":"сообщение; уведомление","vi":"tin nhắn","fa":"پیام","examples":[{"de":"In den Nachrichten kam eine wichtige Meldung.","en":"There was an important news item on the news.","ru":"В новостях было важное сообщение.","vi":"Có một tin nhắn quan trọng trên bản tin.","fa":"پیام مهمی در این خبر وجود داشت."},{"de":"Das Programm zeigt eine Meldung, wenn ein Fehler auftritt.","en":"The program shows a notification when an error occurs.","ru":"Программа показывает уведомление, когда возникает ошибка.","vi":"Chương trình hiển thị thông báo khi xảy ra lỗi.","fa":"در صورت بروز خطا، برنامه پیامی را نمایش می دهد."}]},{"word":"die Melodie","en":"melody","ru":"мелодия","vi":"giai điệu","fa":"ملودی","examples":[{"de":"Die Tänzer bewegten sich im Takt zu einer ruhigen Melodie.","en":"The dancers moved in time to a gentle melody.","ru":"Танцоры двигались в такт спокойной мелодии.","vi":"Các vũ công chuyển động theo giai điệu êm đềm.","fa":"رقصندگان به موقع به یک ملودی آرام حرکت کردند."},{"de":"Den ganzen Tag ging mir diese eingängige Melodie nicht aus dem Kopf.","en":"All day long this catchy melody would not leave my head.","ru":"Весь день эта запоминающаяся мелодия не выходила у меня из головы.","vi":"Cả ngày tôi không thể quên giai điệu hấp dẫn này ra khỏi đầu.","fa":"تمام روز نمی توانستم این ملودی جذاب را از ذهنم بیرون کنم."},{"de":"Er pfiff leise eine alte Melodie vor sich hin.","en":"He quietly whistled an old melody to himself.","ru":"Он тихо насвистывал себе под нос старую мелодию.","vi":"Anh lặng lẽ huýt sáo một giai điệu xưa.","fa":"او به آرامی آهنگی قدیمی را برای خودش سوت زد."}]},{"word":"die Menge","en":"amount, quantity; crowd","ru":"количество; толпа","vi":"đám đông","fa":"جمعیت","examples":[{"de":"Wir brauchen eine große Menge Wasser für das Fest.","en":"We need a large amount of water for the festival.","ru":"Нам нужно большое количество воды для праздника.","vi":"Chúng ta cần một lượng nước lớn cho lễ hội.","fa":"برای جشنواره به مقدار زیادی آب نیاز داریم."},{"de":"Eine riesige Menge Menschen versammelte sich auf dem Platz.","en":"A huge crowd of people gathered in the square.","ru":"Огромная толпа людей собралась на площади.","vi":"Một đám đông khổng lồ tập trung tại quảng trường.","fa":"جمعیت عظیمی از مردم در میدان جمع شده بودند."}]},{"word":"die Mensa","en":"university cafeteria (canteen)","ru":"студенческая столовая","vi":"quán ăn tự phục vụ","fa":"کافه تریا","examples":[{"de":"Wir essen mittags oft in der Mensa.","en":"We often eat lunch at the university cafeteria.","ru":"Мы часто обедаем в студенческой столовой.","vi":"Chúng tôi thường ăn trưa ở căng tin.","fa":"ما اغلب ناهار را در کافه تریا می خوریم."},{"de":"Das Essen in der Mensa ist billig, aber gut.","en":"The food at the cafeteria is cheap but good.","ru":"Еда в столовой дешёвая, но хорошая.","vi":"Đồ ăn ở căng tin rẻ nhưng ngon.","fa":"غذای کافه تریا ارزان اما خوب است."}]},{"word":"der Mensch","en":"human being; person","ru":"человек","vi":"con người","fa":"انسان","examples":[{"de":"Jeder Mensch hat das Recht auf Bildung.","en":"Every human being has the right to education.","ru":"Каждый человек имеет право на образование.","vi":"Mọi người đều có quyền được giáo dục.","fa":"هر فرد حق تحصیل دارد."},{"de":"In der Stadt leben über eine Million Menschen.","en":"More than a million people live in the city.","ru":"В городе живёт более миллиона человек.","vi":"Hơn một triệu người sống ở thành phố.","fa":"بیش از یک میلیون نفر در این شهر زندگی می کنند."}]},{"word":"menschlich","en":"human; humane","ru":"человеческий; гуманный","vi":"con người","fa":"انسان","examples":[{"de":"Es ist ganz menschlich, manchmal Fehler zu machen.","en":"It's quite human to make mistakes sometimes.","ru":"Это вполне по-человечески — иногда ошибаться.","vi":"Đôi khi con người có thể mắc sai lầm.","fa":"این کاملاً انسانی است که گاهی اوقات اشتباه کنیم."},{"de":"Die Chefin behandelt ihre Mitarbeiter sehr menschlich.","en":"The boss treats her employees very humanely.","ru":"Начальница относится к своим сотрудникам очень гуманно.","vi":"Sếp đối xử với nhân viên của mình rất nhân đạo.","fa":"رئیس با کارمندانش بسیار انسانی رفتار می کند."},{"de":"Der menschliche Körper ist erstaunlich komplex.","en":"The human body is amazingly complex.","ru":"Человеческое тело удивительно сложно устроено.","vi":"Cơ thể con người phức tạp đến kinh ngạc.","fa":"بدن انسان به طرز شگفت انگیزی پیچیده است."}]},{"word":"das Menü","en":"menu","ru":"меню","vi":"thực đơn","fa":"منو","examples":[{"de":"Der Kellner bringt uns das Menü.","en":"The waiter brings us the menu.","ru":"Официант приносит нам меню.","vi":"Người phục vụ mang thực đơn đến cho chúng tôi.","fa":"پیشخدمت منو می آورد."},{"de":"Ich nehme heute das Menü mit Suppe und Fleisch.","en":"Today I'll have the set menu with soup and meat.","ru":"Сегодня я возьму комплексный обед с супом и мясом.","vi":"Hôm nay tôi chọn thực đơn có súp và thịt.","fa":"امروز منو با سوپ و گوشت میگیرم."}]},{"word":"merken","en":"to notice; to remember","ru":"замечать; запоминать","vi":"nhớ","fa":"به یاد داشته باشید","examples":[{"de":"Ich habe gemerkt, dass die Tür offen war.","en":"I noticed that the door was open.","ru":"Я заметил, что дверь была открыта.","vi":"Tôi nhận thấy rằng cánh cửa đã mở.","fa":"متوجه شدم در باز است."},{"de":"Kannst du dir seine Telefonnummer merken?","en":"Can you remember his phone number?","ru":"Ты можешь запомнить его номер телефона?","vi":"Bạn có thể nhớ số điện thoại của anh ấy không?","fa":"آیا می توانید شماره تلفن او را به خاطر بسپارید؟"}]},{"word":"merkwürdig","en":"strange, odd","ru":"странный","vi":"kỳ lạ","fa":"عجیب","examples":[{"de":"Es ist merkwürdig, dass niemand auf meine E-Mail geantwortet hat.","en":"It's strange that nobody answered my email.","ru":"Странно, что никто не ответил на моё письмо.","vi":"Thật kỳ lạ là không ai trả lời email của tôi.","fa":"عجیب است که کسی به ایمیل من پاسخ نداد."},{"de":"Ich habe ein merkwürdiges Geräusch im Keller gehört.","en":"I heard a strange noise in the basement.","ru":"Я услышал странный звук в подвале.","vi":"Tôi nghe thấy một tiếng động lạ ở tầng hầm.","fa":"صدای عجیبی در زیرزمین شنیدم."}]},{"word":"die Messe","en":"trade fair; Mass (church service)","ru":"ярмарка, выставка; месса (церковная служба)","vi":"hội chợ","fa":"نمایشگاه","examples":[{"de":"Jedes Jahr besuchen wir die Buchmesse in Frankfurt.","en":"Every year we visit the book fair in Frankfurt.","ru":"Каждый год мы посещаем книжную ярмарку во Франкфурте.","vi":"Hàng năm chúng tôi đều đến thăm hội chợ sách ở Frankfurt.","fa":"هر سال از نمایشگاه کتاب در فرانکفورت بازدید می کنیم."},{"de":"Am Sonntag geht meine Großmutter in die Messe.","en":"On Sunday my grandmother goes to Mass.","ru":"По воскресеньям моя бабушка ходит на мессу.","vi":"Chủ nhật bà tôi đi lễ.","fa":"روز یکشنبه مادربزرگم به عشاء می رود."}]},{"word":"messen","en":"to measure","ru":"измерять","vi":"đo lường","fa":"اندازه گیری","examples":[{"de":"Der Arzt misst meinen Blutdruck.","en":"The doctor measures my blood pressure.","ru":"Врач измеряет моё давление.","vi":"Bác sĩ đo huyết áp của tôi.","fa":"دکتر فشار خونم رو اندازه میگیره"},{"de":"Wir haben die Länge des Zimmers gemessen.","en":"We measured the length of the room.","ru":"Мы измерили длину комнаты.","vi":"Chúng tôi đo chiều dài của căn phòng.","fa":"طول اتاق را اندازه گرفتیم."}]},{"word":"das Messer","en":"knife","ru":"нож","vi":"con dao","fa":"چاقو","examples":[{"de":"Kannst du mir bitte ein scharfes Messer geben?","en":"Can you give me a sharp knife, please?","ru":"Не мог бы ты дать мне острый нож?","vi":"Bạn có thể vui lòng cho tôi một con dao sắc được không?","fa":"میشه لطفا یک چاقوی تیز به من بدهید؟"},{"de":"Sie schneidet das Brot mit einem Messer.","en":"She cuts the bread with a knife.","ru":"Она режет хлеб ножом.","vi":"Cô ấy cắt bánh mì bằng một con dao.","fa":"نان را با چاقو برش می دهد."}]},{"word":"das Metall","en":"metal","ru":"металл","vi":"kim loại","fa":"فلز","examples":[{"de":"Die Brücke besteht aus Metall.","en":"The bridge is made of metal.","ru":"Мост сделан из металла.","vi":"Cây cầu được làm bằng kim loại.","fa":"پل از فلز ساخته شده است."},{"de":"Gold ist ein wertvolles Metall.","en":"Gold is a valuable metal.","ru":"Золото — ценный металл.","vi":"Vàng là một kim loại có giá trị.","fa":"طلا یک فلز ارزشمند است."}]},{"word":"der Metallbauer","en":"metalworker, metal fabricator","ru":"слесарь по металлу, металлообработчик","vi":"thợ kim loại","fa":"فلزکار","examples":[{"de":"Mein Bruder lernt gerade den Beruf des Metallbauers.","en":"My brother is currently training to become a metalworker.","ru":"Мой брат сейчас учится на слесаря по металлу.","vi":"Anh trai tôi hiện đang học làm thợ kim loại.","fa":"برادرم در حال حاضر در حال یادگیری فلزکاری است."},{"de":"Der Metallbauer hat ein neues Geländer für die Treppe gemacht.","en":"The metalworker made a new railing for the stairs.","ru":"Слесарь сделал новые перила для лестницы.","vi":"Người công nhân kim loại đã làm lan can mới cho cầu thang.","fa":"کارگر فلزی نرده جدیدی برای پله ها درست کرد."},{"de":"Als Metallbauer arbeitet man oft mit Stahl und Eisen.","en":"As a metalworker you often work with steel and iron.","ru":"Как слесарю по металлу тебе часто приходится работать со сталью и железом.","vi":"Là một thợ kim loại, bạn thường làm việc với thép và sắt.","fa":"به عنوان یک فلزکار اغلب با فولاد و آهن کار می کنید."}]},{"word":"der Meteorit","en":"meteorite","ru":"метеорит","vi":"thiên thạch","fa":"the meteorite","examples":[{"de":"Der Meteorit schlug in einem Feld ein.","en":"The meteorite struck in a field.","ru":"Метеорит упал в поле.","vi":"Thiên thạch va vào một cánh đồng.","fa":"شهاب سنگ به زمینی برخورد کرد."},{"de":"Im Museum kann man einen echten Meteoriten anfassen.","en":"In the museum you can touch a real meteorite.","ru":"В музее можно потрогать настоящий метеорит.","vi":"Trong bảo tàng bạn có thể chạm vào một thiên thạch thực sự.","fa":"در موزه می توانید یک شهاب سنگ واقعی را لمس کنید."},{"de":"Ein Meteorit ist ein Gesteinsbrocken aus dem All.","en":"A meteorite is a chunk of rock from space.","ru":"Метеорит — это кусок горной породы из космоса.","vi":"Thiên thạch là một mảnh đá từ không gian.","fa":"شهاب سنگ یک تکه سنگ از فضا است."}]},{"word":"die Methode","en":"method","ru":"метод","vi":"phương pháp","fa":"روش","examples":[{"de":"Diese Methode hilft beim Lernen neuer Wörter.","en":"This method helps with learning new words.","ru":"Этот метод помогает в изучении новых слов.","vi":"Phương pháp này giúp học từ mới.","fa":"این روش به یادگیری کلمات جدید کمک می کند."},{"de":"Der Wissenschaftler entwickelte eine neue Methode.","en":"The scientist developed a new method.","ru":"Учёный разработал новый метод.","vi":"Nhà khoa học đã phát triển một phương pháp mới.","fa":"این دانشمند روش جدیدی ابداع کرد."}]},{"word":"die Metropole","en":"metropolis","ru":"мегаполис","vi":"đô thị","fa":"کلان شهر","examples":[{"de":"Berlin ist eine bekannte europäische Metropole.","en":"Berlin is a well-known European metropolis.","ru":"Берлин — известный европейский мегаполис.","vi":"Berlin là một đô thị nổi tiếng của châu Âu.","fa":"برلین یک کلان شهر اروپایی شناخته شده است."},{"de":"In der Metropole gibt es viele Möglichkeiten für junge Leute.","en":"In the metropolis there are many opportunities for young people.","ru":"В мегаполисе много возможностей для молодёжи.","vi":"Có rất nhiều cơ hội cho những người trẻ tuổi ở thủ đô.","fa":"فرصت های زیادی برای جوانان در کلان شهر وجود دارد."}]},{"word":"der Metzger","en":"butcher","ru":"мясник","vi":"người bán thịt","fa":"قصاب","examples":[{"de":"Ich kaufe das Fleisch immer beim Metzger um die Ecke.","en":"I always buy meat at the butcher's around the corner.","ru":"Я всегда покупаю мясо у мясника за углом.","vi":"Tôi luôn mua thịt từ người bán thịt quanh góc phố.","fa":"من همیشه از قصابی در گوشه گوشه گوشت می خرم."},{"de":"Der Metzger empfahl uns ein gutes Stück Fleisch.","en":"The butcher recommended us a good piece of meat.","ru":"Мясник посоветовал нам хороший кусок мяса.","vi":"Người bán thịt giới thiệu cho chúng tôi một miếng thịt ngon.","fa":"قصاب یک تکه گوشت خوب به ما توصیه کرد."}]},{"word":"die Metzgerei","en":"butcher's shop","ru":"мясная лавка, мясной магазин","vi":"cửa hàng bán thịt","fa":"قصابی","examples":[{"de":"Das Fleisch kaufe ich am liebsten in der Metzgerei.","en":"I prefer to buy meat at the butcher's shop.","ru":"Мясо я предпочитаю покупать в мясной лавке.","vi":"Tôi thích mua thịt ở cửa hàng thịt hơn.","fa":"ترجیح می دهم از قصابی گوشت بخرم."},{"de":"In der Metzgerei gibt es heute frische Wurst.","en":"There is fresh sausage at the butcher's today.","ru":"В мясной лавке сегодня есть свежая колбаса.","vi":"Hôm nay có xúc xích tươi ở cửa hàng thịt.","fa":"امروز در قصابی سوسیس تازه هست."},{"de":"Die Metzgerei um die Ecke ist samstags geschlossen.","en":"The butcher's around the corner is closed on Saturdays.","ru":"Мясная лавка за углом по субботам закрыта.","vi":"Cửa hàng bán thịt quanh góc phố đóng cửa vào các ngày thứ Bảy.","fa":"قصابی اطراف شنبه ها تعطیل است."}]},{"word":"die Miete","en":"rent","ru":"аренда; арендная плата","vi":"tiền thuê nhà","fa":"اجاره","examples":[{"de":"Die Miete für die Wohnung ist ziemlich hoch.","en":"The rent for the flat is quite high.","ru":"Арендная плата за квартиру довольно высокая.","vi":"Giá thuê căn hộ khá cao.","fa":"اجاره آپارتمان بسیار بالاست."},{"de":"Ich überweise die Miete immer am Monatsanfang.","en":"I always transfer the rent at the beginning of the month.","ru":"Я всегда перевожу арендную плату в начале месяца.","vi":"Tôi luôn trả tiền thuê nhà vào đầu tháng.","fa":"من همیشه اول ماه اجاره را پرداخت می کنم."}]},{"word":"mieten","en":"to rent","ru":"арендовать, снимать","vi":"thuê","fa":"اجاره","examples":[{"de":"Wir möchten für den Urlaub ein Auto mieten.","en":"We would like to rent a car for the holiday.","ru":"Мы хотим арендовать машину на время отпуска.","vi":"Chúng tôi muốn thuê một chiếc xe hơi cho kỳ nghỉ của chúng tôi.","fa":"ما می خواهیم برای تعطیلات خود یک ماشین اجاره کنیم."},{"de":"Er mietet eine kleine Wohnung in der Innenstadt.","en":"He is renting a small apartment in the city center.","ru":"Он снимает маленькую квартиру в центре города.","vi":"Anh thuê một căn hộ nhỏ ở trung tâm thành phố.","fa":"او یک آپارتمان کوچک در مرکز شهر اجاره می کند."}]},{"word":"der Mieter","en":"tenant","ru":"арендатор; квартиросъёмщик","vi":"người thuê nhà","fa":"مستاجر","examples":[{"de":"Der neue Mieter zieht nächste Woche ein.","en":"The new tenant is moving in next week.","ru":"Новый арендатор въезжает на следующей неделе.","vi":"Người thuê nhà mới sẽ chuyển đến vào tuần tới.","fa":"مستاجر جدید در هفته آینده نقل مکان می کند."},{"de":"Als Mieter hat man bestimmte Rechte und Pflichten.","en":"As a tenant you have certain rights and duties.","ru":"У арендатора есть определённые права и обязанности.","vi":"Là người thuê nhà, bạn có những quyền và nghĩa vụ nhất định.","fa":"به عنوان یک مستاجر، شما حقوق و تعهدات خاصی دارید."}]},{"word":"die Mieterin","en":"tenant (female)","ru":"квартиросъёмщица, нанимательница (женщина)","vi":"người thuê nhà","fa":"مستاجر","examples":[{"de":"Die Mieterin hat die Wohnung sehr ordentlich hinterlassen.","en":"The tenant left the flat very tidy.","ru":"Квартиросъёмщица оставила квартиру очень чистой.","vi":"Người thuê để lại căn hộ rất ngăn nắp.","fa":"مستاجر آپارتمان را بسیار مرتب ترک کرد."},{"de":"Unsere neue Mieterin ist sehr freundlich und ruhig.","en":"Our new tenant is very friendly and quiet.","ru":"Наша новая жилица очень приветливая и тихая.","vi":"Người thuê nhà mới của chúng tôi rất thân thiện và yên tĩnh.","fa":"مستأجر جدید ما بسیار صمیمی و آرام است."},{"de":"Die Mieterin hat den Vertrag fristgerecht gekündigt.","en":"The tenant cancelled the contract on time.","ru":"Квартиросъёмщица вовремя расторгла договор.","vi":"Người thuê nhà chấm dứt hợp đồng đúng thời hạn.","fa":"مستاجر به موقع قرارداد را فسخ کرد."}]},{"word":"der Mietwagen","en":"rental car, hire car","ru":"прокатный автомобиль, машина напрокат","vi":"xe thuê","fa":"ماشین کرایه ای","examples":[{"de":"Am Flughafen haben wir einen Mietwagen abgeholt.","en":"We picked up a hire car at the airport.","ru":"В аэропорту мы забрали прокатный автомобиль.","vi":"Chúng tôi đón một chiếc xe cho thuê tại sân bay.","fa":"از فرودگاه ماشین کرایه ای گرفتیم."},{"de":"Der Mietwagen war kleiner, als wir gedacht hatten.","en":"The rental car was smaller than we'd expected.","ru":"Прокатный автомобиль оказался меньше, чем мы думали.","vi":"Chiếc xe cho thuê nhỏ hơn chúng tôi nghĩ.","fa":"ماشین کرایه ای کوچکتر از آن چیزی بود که فکر می کردیم."},{"de":"Mit dem Mietwagen kann man die Insel gut erkunden.","en":"You can explore the island well with a hire car.","ru":"На прокатном автомобиле можно хорошо исследовать остров.","vi":"Bạn có thể dễ dàng khám phá hòn đảo bằng xe thuê.","fa":"با ماشین کرایه ای می توانید به راحتی جزیره را بگردید."}]},{"word":"der Migrant","en":"migrant","ru":"мигрант","vi":"người di cư","fa":"مهاجر","examples":[{"de":"Viele Migranten suchen in Deutschland Arbeit.","en":"Many migrants look for work in Germany.","ru":"Многие мигранты ищут работу в Германии.","vi":"Nhiều người di cư đang tìm kiếm việc làm ở Đức.","fa":"بسیاری از مهاجران به دنبال کار در آلمان هستند."},{"de":"Die Stadt hilft Migranten bei der Integration.","en":"The city helps migrants with integration.","ru":"Город помогает мигрантам с интеграцией.","vi":"Thành phố giúp người di cư hòa nhập.","fa":"این شهر به مهاجران کمک می کند تا ادغام شوند."}]},{"word":"die Migrantin","en":"migrant (female)","ru":"мигрантка (женщина)","vi":"người di cư","fa":"مهاجر","examples":[{"de":"Die Migrantin arbeitet jetzt als Krankenschwester im Krankenhaus.","en":"The migrant now works as a nurse in the hospital.","ru":"Мигрантка теперь работает медсестрой в больнице.","vi":"Người di cư hiện đang làm y tá trong bệnh viện.","fa":"این مهاجر اکنون به عنوان پرستار در بیمارستان کار می کند."},{"de":"Als Migrantin musste sie sich an eine neue Kultur gewöhnen.","en":"As a migrant she had to get used to a new culture.","ru":"Как мигрантке ей пришлось привыкать к новой культуре.","vi":"Là một người di cư, cô phải làm quen với nền văn hóa mới.","fa":"به عنوان یک مهاجر، او باید به یک فرهنگ جدید عادت می کرد."},{"de":"Die Migrantin hat schnell neue Freunde gefunden.","en":"The migrant quickly made new friends.","ru":"Мигрантка быстро завела новых друзей.","vi":"Người di cư nhanh chóng tìm được những người bạn mới.","fa":"مهاجر به سرعت دوستان جدیدی پیدا کرد."}]},{"word":"die Migration","en":"migration","ru":"миграция","vi":"sự di cư","fa":"مهاجرت","examples":[{"de":"Die Migration nach Europa hat viele Ursachen.","en":"Migration to Europe has many causes.","ru":"У миграции в Европу много причин.","vi":"Di cư sang châu Âu có nhiều nguyên nhân.","fa":"مهاجرت به اروپا دلایل زیادی دارد."},{"de":"Das Land diskutiert über eine neue Politik zur Migration.","en":"The country is discussing a new policy on migration.","ru":"Страна обсуждает новую политику в отношении миграции.","vi":"Đất nước đang thảo luận về một chính sách di cư mới.","fa":"این کشور در حال بحث در مورد سیاست مهاجرتی جدید است."}]},{"word":"das Mikroskop","en":"microscope","ru":"микроскоп","vi":"kính hiển vi","fa":"میکروسکوپ","examples":[{"de":"Unter dem Mikroskop sieht man einzelne Zellen sehr deutlich.","en":"Under the microscope you can see individual cells very clearly.","ru":"Под микроскопом отдельные клетки видны очень отчётливо.","vi":"Các tế bào riêng lẻ có thể được nhìn thấy rất rõ ràng dưới kính hiển vi.","fa":"سلول های منفرد را می توان به وضوح زیر میکروسکوپ دید."},{"de":"Die Schüler durften zum ersten Mal durch ein echtes Mikroskop schauen.","en":"For the first time, the pupils were allowed to look through a real microscope.","ru":"Ученикам впервые разрешили посмотреть в настоящий микроскоп.","vi":"Lần đầu tiên các sinh viên có thể nhìn qua kính hiển vi thực sự.","fa":"دانش آموزان توانستند برای اولین بار از طریق یک میکروسکوپ واقعی نگاه کنند."},{"de":"Ohne ein Mikroskop kann man Bakterien gar nicht erkennen.","en":"Without a microscope you cannot detect bacteria at all.","ru":"Без микроскопа бактерии вообще нельзя разглядеть.","vi":"Không có kính hiển vi bạn không thể nhìn thấy vi khuẩn.","fa":"بدون میکروسکوپ نمی توانید باکتری ها را ببینید."}]},{"word":"die Milch","en":"milk","ru":"молоко","vi":"sữa","fa":"شیر","examples":[{"de":"Ich trinke morgens gern ein Glas Milch.","en":"In the morning I like to drink a glass of milk.","ru":"Утром я люблю пить стакан молока.","vi":"Tôi thích uống một ly sữa vào buổi sáng.","fa":"من دوست دارم صبح یک لیوان شیر بخورم."},{"de":"Kannst du bitte Milch für den Kaffee kaufen?","en":"Can you please buy milk for the coffee?","ru":"Можешь купить молока для кофе?","vi":"Bạn có thể vui lòng mua sữa cho cà phê được không?","fa":"میشه لطفا برای قهوه شیر بخرید؟"}]},{"word":"der Milchshake","en":"milkshake","ru":"молочный коктейль","vi":"sữa lắc","fa":"میلک شیک","examples":[{"de":"Die Kinder teilten sich einen großen Milchshake.","en":"The children shared a large milkshake.","ru":"Дети поделили один большой молочный коктейль.","vi":"Bọn trẻ chia nhau một ly sữa lắc lớn.","fa":"بچه ها یک میلک شیک بزرگ به اشتراک گذاشتند."},{"de":"Dieser Milchshake schmeckt nach Erdbeere.","en":"This milkshake tastes of strawberry.","ru":"Этот молочный коктейль на вкус как клубника.","vi":"Món sữa lắc này có vị như dâu tây.","fa":"طعم این میلک شیک شبیه توت فرنگی است."},{"de":"Der Milchshake war so dick, dass der Strohhalm verstopfte.","en":"The milkshake was so thick that the straw got blocked.","ru":"Молочный коктейль был таким густым, что трубочка забилась.","vi":"Sữa lắc đặc đến mức làm tắc ống hút.","fa":"میلک شیک آنقدر غلیظ بود که نی را مسدود می کرد."}]},{"word":"mild","en":"mild","ru":"мягкий, умеренный","vi":"nhẹ nhàng","fa":"خفیف","examples":[{"de":"Der Winter war dieses Jahr sehr mild.","en":"The winter was very mild this year.","ru":"Зима в этом году была очень мягкой.","vi":"Mùa đông năm nay rất ôn hòa.","fa":"زمستان امسال بسیار معتدل بود."},{"de":"Ich mag diesen Käse, weil er mild schmeckt.","en":"I like this cheese because it tastes mild.","ru":"Мне нравится этот сыр, потому что у него мягкий вкус.","vi":"Tôi thích loại phô mai này vì nó có vị nhẹ.","fa":"من این پنیر را دوست دارم چون طعم ملایمی دارد."}]},{"word":"der Millionär","en":"millionaire","ru":"миллионер","vi":"triệu phú","fa":"میلیونر","examples":[{"de":"Patrick wird vielleicht bald Millionär.","en":"Patrick might soon become a millionaire.","ru":"Патрик, возможно, скоро станет миллионером.","vi":"Patrick có thể sớm trở thành triệu phú.","fa":"پاتریک ممکن است به زودی میلیونر شود."},{"de":"Der Millionär spendete viel Geld für das Krankenhaus.","en":"The millionaire donated a lot of money to the hospital.","ru":"Миллионер пожертвовал больнице много денег.","vi":"Triệu phú đã quyên góp rất nhiều tiền cho bệnh viện.","fa":"این میلیونر پول زیادی به بیمارستان اهدا کرد."},{"de":"Als Millionär könnte ich die ganze Welt bereisen.","en":"As a millionaire I could travel the whole world.","ru":"Будучи миллионером, я мог бы объехать весь мир.","vi":"Nếu tôi là triệu phú, tôi có thể đi du lịch khắp thế giới.","fa":"اگر میلیونر بودم می توانستم به تمام دنیا سفر کنم."}]},{"word":"die Minderheit","en":"minority","ru":"меньшинство","vi":"thiểu số","fa":"اقلیت","examples":[{"de":"Nur eine Minderheit der Bevölkerung stimmte dagegen.","en":"Only a minority of the population voted against it.","ru":"Против проголосовало лишь меньшинство населения.","vi":"Chỉ có một thiểu số dân chúng bỏ phiếu chống lại nó.","fa":"تنها اقلیتی از مردم به آن رای منفی دادند."},{"de":"Der Verein schützt die Rechte nationaler Minderheiten.","en":"The association protects the rights of national minorities.","ru":"Организация защищает права национальных меньшинств.","vi":"Hiệp hội bảo vệ quyền lợi của các dân tộc thiểu số.","fa":"این انجمن از حقوق اقلیت های ملی حمایت می کند."}]},{"word":"mindestens","en":"at least","ru":"по крайней мере, как минимум","vi":"ít nhất","fa":"حداقل","examples":[{"de":"Du solltest mindestens acht Stunden schlafen.","en":"You should sleep at least eight hours.","ru":"Тебе следует спать как минимум восемь часов.","vi":"Bạn nên ngủ ít nhất tám giờ.","fa":"شما باید حداقل هشت ساعت بخوابید."},{"de":"Die Fahrt dauert mindestens zwei Stunden.","en":"The trip takes at least two hours.","ru":"Поездка длится по крайней мере два часа.","vi":"Cuộc hành trình mất ít nhất hai giờ.","fa":"سفر حداقل دو ساعت طول می کشد."}]},{"word":"der Mindestlohn","en":"minimum wage","ru":"минимальная зарплата, минимальный размер оплаты труда","vi":"mức lương tối thiểu","fa":"حداقل دستمزد","examples":[{"de":"In Deutschland gibt es einen gesetzlichen Mindestlohn.","en":"In Germany there is a statutory minimum wage.","ru":"В Германии есть установленная законом минимальная зарплата.","vi":"Ở Đức có mức lương tối thiểu hợp pháp.","fa":"در آلمان حداقل دستمزد قانونی وجود دارد."},{"de":"Der Mindestlohn wurde dieses Jahr wieder erhöht.","en":"The minimum wage was raised again this year.","ru":"В этом году минимальную зарплату снова повысили.","vi":"Mức lương tối thiểu đã tăng trở lại trong năm nay.","fa":"حداقل دستمزد امسال دوباره افزایش یافت."},{"de":"Jeder Arbeitnehmer hat ein Recht auf den Mindestlohn.","en":"Every employee has a right to the minimum wage.","ru":"Каждый работник имеет право на минимальную зарплату.","vi":"Mọi nhân viên đều có quyền được hưởng mức lương tối thiểu.","fa":"هر کارمند حق دریافت حداقل دستمزد را دارد."}]},{"word":"das Mineralwasser","en":"mineral water","ru":"минеральная вода","vi":"nước khoáng","fa":"آب معدنی","examples":[{"de":"Bitte bringen Sie mir eine Flasche Mineralwasser.","en":"Please bring me a bottle of mineral water.","ru":"Принесите мне, пожалуйста, бутылку минеральной воды.","vi":"Vui lòng mang cho tôi một chai nước khoáng.","fa":"لطفا برای من یک بطری آب معدنی بیاورید."},{"de":"Er trinkt lieber Mineralwasser als Limonade.","en":"He prefers to drink mineral water rather than soda.","ru":"Он предпочитает пить минеральную воду, а не лимонад.","vi":"Anh ấy thích uống nước khoáng hơn nước chanh.","fa":"او نوشیدن آب معدنی را به لیموناد ترجیح می دهد."}]},{"word":"minimal","en":"minimal","ru":"минимальный","vi":"tối thiểu","fa":"حداقل","examples":[{"de":"Der Unterschied zwischen den beiden Preisen ist minimal.","en":"The difference between the two prices is minimal.","ru":"Разница между этими двумя ценами минимальна.","vi":"Sự khác biệt giữa hai mức giá là tối thiểu.","fa":"تفاوت بین این دو قیمت حداقل است."},{"de":"Wir hatten nur minimale Probleme mit dem neuen System.","en":"We only had minimal problems with the new system.","ru":"У нас были лишь минимальные проблемы с новой системой.","vi":"Chúng tôi gặp rất ít vấn đề với hệ thống mới.","fa":"ما با سیستم جدید کمترین مشکل را داشتیم."}]},{"word":"der Minirock","en":"miniskirt","ru":"мини-юбка","vi":"chiếc váy ngắn","fa":"دامن کوتاه","examples":[{"de":"Im Sommer trägt sie gern einen kurzen Minirock.","en":"In summer she likes to wear a short miniskirt.","ru":"Летом она любит носить короткую мини-юбку.","vi":"Vào mùa hè, cô ấy thích mặc váy ngắn.","fa":"در تابستان او دوست دارد یک دامن کوتاه کوتاه بپوشد."},{"de":"Der Minirock kam in den sechziger Jahren in Mode.","en":"The miniskirt came into fashion in the sixties.","ru":"Мини-юбка вошла в моду в шестидесятые годы.","vi":"Váy mini trở thành mốt vào những năm sáu mươi.","fa":"دامن مینی در دهه شصت مد شد."},{"de":"Zu dem Minirock passt eine helle Bluse.","en":"A light blouse goes well with the miniskirt.","ru":"К мини-юбке хорошо подходит лёгкая блузка.","vi":"Một chiếc áo cánh nhẹ rất hợp với váy ngắn.","fa":"یک بلوز سبک به خوبی با دامن مینی ست می شود."}]},{"word":"mischen","en":"to mix","ru":"смешивать","vi":"trộn","fa":"مخلوط کردن","examples":[{"de":"Man muss Mehl, Eier und Milch gut mischen.","en":"You have to mix flour, eggs and milk well.","ru":"Нужно хорошо смешать муку, яйца и молоко.","vi":"Bạn phải trộn đều bột mì, trứng và sữa.","fa":"آرد، تخم مرغ و شیر را باید خوب مخلوط کنید."},{"de":"Er mischt gern verschiedene Musikstile in seinen Songs.","en":"He likes to mix different music styles in his songs.","ru":"Он любит смешивать разные музыкальные стили в своих песнях.","vi":"Anh ấy thích kết hợp các phong cách âm nhạc khác nhau trong các bài hát của mình.","fa":"او دوست دارد سبک های مختلف موسیقی را در آهنگ هایش ترکیب کند."}]},{"word":"miss-","en":"mis- (prefix expressing failure or wrongness)","ru":"приставка со значением неудачи или ошибочности (mis-)","vi":"nhầm","fa":"اشتباه","examples":[{"de":"Das Vorsilbe miss- drückt oft etwas Negatives aus, wie in missverstehen.","en":"The prefix mis- often expresses something negative, as in to misunderstand.","ru":"Приставка mis- часто выражает что-то негативное, как в missverstehen (неправильно понять).","vi":"Tiền tố thường diễn đạt sai điều gì đó tiêu cực, như hiểu lầm.","fa":"پیشوند mis- اغلب چیزی منفی را بیان می کند، مانند سوءتفاهم."},{"de":"Wir haben uns leider missverstanden.","en":"Unfortunately we misunderstood each other.","ru":"К сожалению, мы друг друга неправильно поняли.","vi":"Thật không may, chúng tôi đã hiểu lầm nhau.","fa":"متاسفانه ما همدیگر را اشتباه متوجه شدیم."},{"de":"Sein Verhalten missfiel allen im Team.","en":"His behaviour displeased everyone in the team.","ru":"Его поведение вызвало недовольство всей команды.","vi":"Hành vi của anh ấy khiến mọi người trong nhóm không hài lòng.","fa":"رفتار او باعث نارضایتی همه اعضای تیم شد."}]},{"word":"der Misserfolg","en":"failure","ru":"неудача; провал","vi":"sự thất bại","fa":"شکست","examples":[{"de":"Nach dem Misserfolg gab er nicht auf.","en":"After the failure he didn't give up.","ru":"После неудачи он не сдался.","vi":"Sau thất bại, anh không bỏ cuộc.","fa":"پس از شکست، او تسلیم نشد."},{"de":"Aus einem Misserfolg kann man viel lernen.","en":"You can learn a lot from a failure.","ru":"Из неудачи можно многому научиться.","vi":"Bạn có thể học được rất nhiều từ thất bại.","fa":"شما می توانید از شکست چیزهای زیادی یاد بگیرید."}]},{"word":"mit","en":"with","ru":"с (кем-л./чем-л.)","vi":"với","fa":"با","examples":[{"de":"Ich fahre mit dem Bus zur Schule.","en":"I go to school by bus.","ru":"Я езжу в школу на автобусе.","vi":"Tôi đi xe buýt đến trường.","fa":"با اتوبوس به مدرسه می روم."},{"de":"Sie spricht gern mit ihren Freunden über Filme.","en":"She likes to talk with her friends about movies.","ru":"Она любит разговаривать с друзьями о фильмах.","vi":"Cô ấy thích nói chuyện về phim ảnh với bạn bè.","fa":"او دوست دارد با دوستانش درباره فیلم صحبت کند."}]},{"word":"der Mitarbeiter","en":"employee; colleague","ru":"сотрудник","vi":"nhân viên","fa":"کارمند","examples":[{"de":"Die Firma hat über zweihundert Mitarbeiter.","en":"The company has more than two hundred employees.","ru":"В компании работает более двухсот сотрудников.","vi":"Công ty có hơn hai trăm nhân viên.","fa":"این شرکت بیش از دویست کارمند دارد."},{"de":"Ein freundlicher Mitarbeiter half mir bei meiner Frage.","en":"A friendly employee helped me with my question.","ru":"Дружелюбный сотрудник помог мне с моим вопросом.","vi":"Một nhân viên thân thiện đã giúp tôi giải đáp thắc mắc.","fa":"یک کارمند صمیمی در مورد سوالم به من کمک کرد."}]},{"word":"das Mitarbeitergespräch","en":"staff appraisal, employee review meeting","ru":"собеседование с сотрудником, беседа руководителя с работником (оценочная)","vi":"cuộc phỏng vấn nhân viên","fa":"مصاحبه کارمند","examples":[{"de":"Morgen habe ich mein jährliches Mitarbeitergespräch mit der Chefin.","en":"Tomorrow I have my annual appraisal meeting with the boss.","ru":"Завтра у меня ежегодная беседа с начальником.","vi":"Ngày mai tôi có buổi đánh giá hiệu suất hàng năm với sếp.","fa":"فردا بررسی عملکرد سالانه خود را با رئیس دارم."},{"de":"Im Mitarbeitergespräch sprechen wir über meine Ziele.","en":"In the staff appraisal we talk about my goals.","ru":"На беседе с сотрудником мы обсуждаем мои цели.","vi":"Trong cuộc phỏng vấn nhân viên, chúng tôi nói về mục tiêu của tôi.","fa":"در مصاحبه کارمند ما در مورد اهداف من صحبت می کنیم."},{"de":"Das Mitarbeitergespräch dauerte fast eine Stunde.","en":"The appraisal meeting lasted almost an hour.","ru":"Беседа длилась почти час.","vi":"Cuộc phỏng vấn nhân viên kéo dài gần một giờ.","fa":"مصاحبه کارمند تقریبا یک ساعت طول کشید."}]},{"word":"die Mitarbeiterin","en":"employee, member of staff (female)","ru":"сотрудница, работница","vi":"nhân viên","fa":"کارمند","examples":[{"de":"Unsere neue Mitarbeiterin ist sehr nett und hilfsbereit.","en":"Our new employee is very nice and helpful.","ru":"Наша новая сотрудница очень милая и отзывчивая.","vi":"Nhân viên mới của chúng tôi rất tốt bụng và hữu ích.","fa":"کارمند جدید ما بسیار خوب و مفید است."},{"de":"Die Mitarbeiterin an der Kasse hat mir schnell geholfen.","en":"The employee at the till helped me quickly.","ru":"Сотрудница на кассе быстро мне помогла.","vi":"Nhân viên ở quầy thanh toán đã giúp tôi nhanh chóng.","fa":"کارمند صندوق به سرعت به من کمک کرد."},{"de":"Jede Mitarbeiterin bekommt im Sommer dreißig Tage Urlaub.","en":"Every female employee gets thirty days of holiday in summer.","ru":"Каждая сотрудница получает летом тридцать дней отпуска.","vi":"Mỗi nhân viên được nghỉ 30 ngày vào mùa hè.","fa":"هر کارمند در تابستان سی روز مرخصی دارد."}]},{"word":"miteinander","en":"with each other; together","ru":"друг с другом, вместе","vi":"với nhau","fa":"با یکدیگر","examples":[{"de":"Die Kinder spielen gern miteinander im Park.","en":"The children like to play together in the park.","ru":"Дети любят играть друг с другом в парке.","vi":"Trẻ em vui chơi cùng nhau trong công viên.","fa":"بچه ها از بازی با هم در پارک لذت می برند."},{"de":"Wir sollten öfter miteinander reden.","en":"We should talk with each other more often.","ru":"Нам стоит чаще разговаривать друг с другом.","vi":"Chúng ta nên nói chuyện với nhau thường xuyên hơn.","fa":"ما باید بیشتر با هم صحبت کنیم."}]},{"word":"das Mitglied","en":"member","ru":"член (организации, клуба)","vi":"thành viên","fa":"عضو","examples":[{"de":"Er ist Mitglied in einem Fußballverein.","en":"He is a member of a football club.","ru":"Он член футбольного клуба.","vi":"Anh ấy là thành viên của một câu lạc bộ bóng đá.","fa":"او عضو یک باشگاه فوتبال است."},{"de":"Neue Mitglieder sind in unserem Verein immer willkommen.","en":"New members are always welcome in our club.","ru":"Новые члены всегда рады в нашем клубе.","vi":"Các thành viên mới luôn được chào đón trong câu lạc bộ của chúng tôi.","fa":"اعضای جدید همیشه در باشگاه ما پذیرفته می شوند."}]},{"word":"die Mitte","en":"middle, center","ru":"середина, центр","vi":"ở giữa","fa":"وسط","examples":[{"de":"Das Denkmal steht in der Mitte des Platzes.","en":"The monument stands in the middle of the square.","ru":"Памятник стоит в центре площади.","vi":"Tượng đài đứng giữa quảng trường.","fa":"بنای یادبود در وسط میدان قرار دارد."},{"de":"Wir treffen uns in der Mitte der Woche.","en":"We're meeting in the middle of the week.","ru":"Мы встречаемся в середине недели.","vi":"Chúng ta sẽ gặp nhau vào giữa tuần.","fa":"وسط هفته همدیگر را می بینیم."}]},{"word":"mitteilen","en":"to inform, to tell (communicate)","ru":"сообщать","vi":"giao tiếp","fa":"ارتباط برقرار کنند","examples":[{"de":"Der Lehrer teilte den Schülern die Prüfungstermine mit.","en":"The teacher informed the students of the exam dates.","ru":"Учитель сообщил ученикам о датах экзаменов.","vi":"Giáo viên thông báo cho học sinh về ngày thi.","fa":"معلم تاریخ امتحانات را به دانش آموزان اطلاع داد."},{"de":"Bitte teilen Sie uns Ihre Entscheidung bis Freitag mit.","en":"Please let us know your decision by Friday.","ru":"Пожалуйста, сообщите нам о своём решении до пятницы.","vi":"Vui lòng cho chúng tôi biết quyết định của bạn trước thứ Sáu.","fa":"لطفا تصمیم خود را تا جمعه به ما اطلاع دهید."}]},{"word":"das Mittel","en":"means; remedy","ru":"средство","vi":"phương tiện","fa":"وسیله","examples":[{"de":"Sport ist ein gutes Mittel gegen Stress.","en":"Sport is a good remedy against stress.","ru":"Спорт — хорошее средство от стресса.","vi":"Thể thao là một phương pháp chữa trị tốt cho căng thẳng.","fa":"ورزش درمان خوبی برای استرس است."},{"de":"Wir haben nicht genug Mittel, um das Projekt zu finanzieren.","en":"We don't have enough means to finance the project.","ru":"У нас недостаточно средств, чтобы профинансировать проект.","vi":"Chúng tôi không có đủ vốn để tài trợ cho dự án.","fa":"بودجه کافی برای تامین مالی پروژه نداریم."}]},{"word":"mitten","en":"in the middle (of)","ru":"посреди, прямо в середине","vi":"ở giữa","fa":"وسط","examples":[{"de":"Das Auto hielt mitten auf der Straße an.","en":"The car stopped right in the middle of the street.","ru":"Машина остановилась прямо посреди улицы.","vi":"Xe dừng lại giữa đường.","fa":"ماشین وسط خیابان ایستاد."},{"de":"Sie wohnen mitten in der Stadt.","en":"They live right in the middle of the city.","ru":"Они живут прямо в центре города.","vi":"Bạn sống ở giữa thành phố.","fa":"شما در وسط شهر زندگی می کنید."}]},{"word":"mittler","en":"middle, average, medium","ru":"средний","vi":"trung bình","fa":"متوسط","examples":[{"de":"Er hat einen mittleren Schulabschluss gemacht.","en":"He obtained an intermediate school-leaving certificate.","ru":"Он получил аттестат о среднем образовании.","vi":"Anh ấy có bằng tốt nghiệp trung học cơ sở.","fa":"او دارای دیپلم متوسطه است."},{"de":"Das Hotel liegt in einer mittleren Preisklasse.","en":"The hotel is in a mid-range price category.","ru":"Отель в среднем ценовом сегменте.","vi":"Khách sạn nằm trong tầm giá trung bình.","fa":"این هتل در محدوده قیمتی متوسط ​​قرار دارد."},{"de":"Die mittlere Temperatur im Juli liegt bei 25 Grad.","en":"The average temperature in July is around 25 degrees.","ru":"Средняя температура в июле около 25 градусов.","vi":"Nhiệt độ trung bình vào tháng 7 là 25 độ.","fa":"میانگین دما در ماه جولای 25 درجه است."}]},{"word":"mittler-","en":"middle, medium (adjective stem, e.g. 'mittlere' = middle/medium)","ru":"средний (основа прилагательного, напр. 'mittlere' — средний)","vi":"trung bình","fa":"متوسط","examples":[{"de":"Er ist von mittlerer Größe.","en":"He is of medium height.","ru":"Он среднего роста.","vi":"Anh ấy có kích thước trung bình.","fa":"او سایز متوسطی دارد."},{"de":"Die mittlere Temperatur im Juli liegt bei 25 Grad.","en":"The average temperature in July is 25 degrees.","ru":"Средняя температура в июле — 25 градусов.","vi":"Nhiệt độ trung bình vào tháng 7 là 25 độ.","fa":"میانگین دما در ماه جولای 25 درجه است."}]},{"word":"mittlerweile","en":"meanwhile, by now","ru":"тем временем, к настоящему моменту","vi":"trong khi đó","fa":"در همین حال","examples":[{"de":"Mittlerweile spricht er sehr gut Deutsch.","en":"By now he speaks German very well.","ru":"К настоящему моменту он очень хорошо говорит по-немецки.","vi":"Bây giờ anh ấy nói tiếng Đức rất tốt.","fa":"او اکنون به خوبی آلمانی صحبت می کند."},{"de":"Ich habe mittlerweile eine neue Wohnung gefunden.","en":"Meanwhile, I have found a new apartment.","ru":"Тем временем я нашёл новую квартиру.","vi":"Bây giờ tôi đã tìm được một căn hộ mới.","fa":"اکنون یک آپارتمان جدید پیدا کرده ام."}]},{"word":"das Möbel","en":"piece of furniture (usually plural: furniture)","ru":"предмет мебели (обычно во мн.ч. — мебель)","vi":"đồ nội thất","fa":"مبلمان","examples":[{"de":"Wir haben neue Möbel für das Wohnzimmer gekauft.","en":"We bought new furniture for the living room.","ru":"Мы купили новую мебель для гостиной.","vi":"Chúng tôi đã mua đồ nội thất mới cho phòng khách.","fa":"مبلمان جدید برای اتاق نشیمن خریدیم."},{"de":"Dieses Möbelstück ist aus massivem Holz.","en":"This piece of furniture is made of solid wood.","ru":"Этот предмет мебели сделан из массива дерева.","vi":"Mảnh đồ nội thất này được làm bằng gỗ nguyên khối.","fa":"این تکه مبلمان از چوب جامد ساخته شده است."}]},{"word":"mobil","en":"mobile","ru":"мобильный, подвижный","vi":"di động","fa":"موبایل","examples":[{"de":"Mit dem Rollstuhl bleibt sie trotzdem mobil.","en":"With the wheelchair she still stays mobile.","ru":"С инвалидным креслом она всё равно остаётся мобильной.","vi":"Cô vẫn di chuyển bằng xe lăn.","fa":"او همچنان با ویلچر متحرک است."},{"de":"Er arbeitet oft mit seinem mobilen Gerät im Café.","en":"He often works with his mobile device at the café.","ru":"Он часто работает со своим мобильным устройством в кафе.","vi":"Anh ấy thường làm việc với thiết bị di động của mình trong quán cà phê.","fa":"او اغلب با موبایل خود در کافه کار می کند."}]},{"word":"die Mobilbox","en":"voicemail (mobile mailbox)","ru":"голосовая почта (на мобильном)","vi":"hộp di động","fa":"جعبه موبایل","examples":[{"de":"Ich konnte dich nicht erreichen, also habe ich auf deine Mobilbox gesprochen.","en":"I couldn't reach you, so I left a message on your voicemail.","ru":"Я не смог до тебя дозвониться и оставил сообщение на голосовой почте.","vi":"Tôi không liên lạc được với bạn nên tôi đã nói chuyện với thư thoại của bạn.","fa":"من نتوانستم با شما تماس بگیرم، بنابراین با پیام صوتی شما صحبت کردم."},{"de":"Bitte hinterlassen Sie eine Nachricht auf der Mobilbox.","en":"Please leave a message on the voicemail.","ru":"Оставьте, пожалуйста, сообщение на голосовой почте.","vi":"Vui lòng để lại tin nhắn trên hộp thư thoại.","fa":"لطفا در پست صوتی پیام بگذارید."},{"de":"Ich höre meine Mobilbox erst heute Abend ab.","en":"I'll only check my voicemail this evening.","ru":"Я проверю голосовую почту только вечером.","vi":"Tôi sẽ không nghe thư thoại của mình cho đến tối nay.","fa":"من تا امروز عصر به پیام صوتی خود گوش نمی دهم."}]},{"word":"möbliert","en":"furnished","ru":"меблированный","vi":"trang bị nội thất","fa":"مبله شده","examples":[{"de":"Wir suchen eine möblierte Wohnung für ein halbes Jahr.","en":"We're looking for a furnished flat for half a year.","ru":"Мы ищем меблированную квартиру на полгода.","vi":"Chúng tôi đang tìm kiếm một căn hộ đầy đủ tiện nghi trong sáu tháng.","fa":"به دنبال آپارتمان مبله شش ماهه هستیم."},{"de":"Das Zimmer ist komplett möbliert.","en":"The room is fully furnished.","ru":"Комната полностью меблирована.","vi":"Phòng được trang bị đầy đủ tiện nghi.","fa":"اتاق کاملا مبله است."},{"de":"Möblierte Apartments sind oft teurer als leere.","en":"Furnished apartments are often more expensive than empty ones.","ru":"Меблированные квартиры часто дороже пустых.","vi":"Căn hộ có sẵn nội thất thường đắt hơn căn hộ trống.","fa":"آپارتمان های مبله اغلب گران تر از آپارتمان های خالی هستند."}]},{"word":"möchten","en":"would like (to)","ru":"хотел(а) бы","vi":"muốn","fa":"می خواهم","examples":[{"de":"Ich möchte gern einen Kaffee bestellen.","en":"I would like to order a coffee.","ru":"Я хотел бы заказать кофе.","vi":"Tôi muốn gọi một ly cà phê.","fa":"من می خواهم یک قهوه سفارش بدهم."},{"de":"Möchtest du mit uns ins Kino gehen?","en":"Would you like to go to the cinema with us?","ru":"Хочешь пойти с нами в кино?","vi":"Bạn có muốn đi xem phim với chúng tôi không?","fa":"آیا دوست دارید با ما به سینما بروید؟"}]},{"word":"die Mode","en":"fashion","ru":"мода","vi":"thời trang","fa":"مد","examples":[{"de":"Sie interessiert sich sehr für Mode.","en":"She is very interested in fashion.","ru":"Она очень интересуется модой.","vi":"Cô ấy rất quan tâm đến thời trang.","fa":"او به مد علاقه زیادی دارد."},{"de":"Diese Frisur war in den Neunzigern große Mode.","en":"This hairstyle was very fashionable in the nineties.","ru":"Эта причёска была очень модной в девяностые.","vi":"Kiểu tóc này rất phổ biến vào những năm 90.","fa":"این مدل مو در دهه نود بزرگ بود."}]},{"word":"das Modell","en":"model","ru":"модель","vi":"người mẫu","fa":"مدل","examples":[{"de":"Dieses Auto ist das neueste Modell der Firma.","en":"This car is the company's newest model.","ru":"Эта машина — новейшая модель компании.","vi":"Chiếc xe này là mẫu mới nhất của hãng.","fa":"این خودرو جدیدترین مدل این شرکت است."},{"de":"Der Architekt baute ein Modell des Gebäudes.","en":"The architect built a model of the building.","ru":"Архитектор построил модель здания.","vi":"Kiến trúc sư đã xây dựng mô hình của tòa nhà.","fa":"معمار مدلی از ساختمان را ساخت."}]},{"word":"modern","en":"modern","ru":"современный","vi":"hiện đại","fa":"مدرن","examples":[{"de":"Die Wohnung ist modern eingerichtet.","en":"The apartment is furnished in a modern style.","ru":"Квартира обставлена в современном стиле.","vi":"Căn hộ được trang bị nội thất hiện đại.","fa":"آپارتمان مبله مدرن است."},{"de":"Moderne Technik erleichtert unseren Alltag.","en":"Modern technology makes our everyday life easier.","ru":"Современная техника облегчает нашу повседневную жизнь.","vi":"Công nghệ hiện đại làm cho cuộc sống hàng ngày của chúng ta dễ dàng hơn.","fa":"تکنولوژی مدرن زندگی روزمره ما را آسان تر می کند."}]},{"word":"der Modeschneider","en":"fashion tailor, dressmaker","ru":"модельер, портной (женской одежды)","vi":"thợ may thời trang","fa":"خیاط مد","examples":[{"de":"Der Modeschneider näht jedes Kleid nach Maß.","en":"The fashion tailor sews every dress to measure.","ru":"Модельер шьёт каждое платье по мерке.","vi":"Người thợ may thời trang may từng chiếc váy theo số đo.","fa":"خیاط مد هر لباس را به اندازه می دوزد."},{"de":"Sie lässt ihre Kleider von einem teuren Modeschneider machen.","en":"She has her clothes made by an expensive fashion tailor.","ru":"Она заказывает одежду у дорогого модельера.","vi":"Cô ấy có quần áo do một thợ may thời trang đắt tiền may.","fa":"او لباس هایش را توسط یک خیاط گران قیمت مد ساخته است."},{"de":"Als Modeschneider braucht man viel Geschick und Geduld.","en":"As a fashion tailor you need a lot of skill and patience.","ru":"Модельеру нужно много мастерства и терпения.","vi":"Nghề thợ may thời trang đòi hỏi rất nhiều kỹ năng và sự kiên nhẫn.","fa":"خیاط مد نیاز به مهارت و صبر زیادی دارد."}]},{"word":"mögen","en":"to like","ru":"нравиться, любить","vi":"thích","fa":"دوست داشتن","examples":[{"de":"Ich mag klassische Musik sehr gern.","en":"I like classical music a lot.","ru":"Мне очень нравится классическая музыка.","vi":"Ich mag klassische Musik sehr gern.","fa":"من موسیقی کلاسیک را خیلی دوست دارم."},{"de":"Magst du lieber Tee oder Kaffee?","en":"Do you prefer tea or coffee?","ru":"Что тебе больше нравится: чай или кофе?","vi":"Do you prefer tea or coffee?","fa":"چای را ترجیح می دهید یا قهوه؟"}]},{"word":"möglich","en":"possible","ru":"возможный","vi":"có thể","fa":"ممکن است","examples":[{"de":"Ist es möglich, den Termin zu verschieben?","en":"Is it possible to postpone the appointment?","ru":"Возможно ли перенести встречу?","vi":"Có thể dời lại cuộc hẹn được không?","fa":"آیا امکان تغییر نوبت وجود دارد؟"},{"de":"Wir müssen so schnell wie möglich handeln.","en":"We have to act as quickly as possible.","ru":"Нам нужно действовать как можно быстрее.","vi":"Chúng ta phải hành động càng nhanh càng tốt.","fa":"ما باید هر چه سریعتر اقدام کنیم."}]},{"word":"möglicherweise","en":"possibly, perhaps","ru":"возможно, может быть","vi":"có thể","fa":"احتمالا","examples":[{"de":"Möglicherweise regnet es morgen.","en":"It will possibly rain tomorrow.","ru":"Возможно, завтра пойдёт дождь.","vi":"Ngày mai trời có thể mưa.","fa":"ممکنه فردا بارون بباره"},{"de":"Wir kommen möglicherweise etwas später.","en":"We may possibly arrive a little later.","ru":"Мы, возможно, приедем чуть позже.","vi":"Chúng tôi có thể đến muộn hơn một chút.","fa":"شاید کمی دیرتر بیاییم"},{"de":"Das hat möglicherweise mit dem Wetter zu tun.","en":"That possibly has something to do with the weather.","ru":"Это, возможно, как-то связано с погодой.","vi":"Điều này có thể có liên quan đến thời tiết.","fa":"این ممکن است ربطی به آب و هوا داشته باشد."}]},{"word":"die Möglichkeit","en":"possibility; opportunity","ru":"возможность","vi":"khả năng","fa":"امکان","examples":[{"de":"Es gibt mehrere Möglichkeiten, dieses Problem zu lösen.","en":"There are several ways to solve this problem.","ru":"Есть несколько способов решить эту проблему.","vi":"Có một số cách để giải quyết vấn đề này.","fa":"راه های مختلفی برای حل این مشکل وجود دارد."},{"de":"Ich hatte noch nie die Möglichkeit, ins Ausland zu reisen.","en":"I have never had the opportunity to travel abroad.","ru":"У меня никогда не было возможности поехать за границу.","vi":"Tôi chưa bao giờ có cơ hội đi du lịch nước ngoài.","fa":"من هرگز فرصت سفر خارج از کشور را نداشتم."}]},{"word":"möglichst","en":"as ... as possible","ru":"как можно (более)","vi":"có thể","fa":"ممکن است","examples":[{"de":"Bitte antworten Sie möglichst schnell.","en":"Please reply as quickly as possible.","ru":"Пожалуйста, ответьте как можно быстрее.","vi":"Hãy trả lời càng nhanh càng tốt.","fa":"لطفا در اسرع وقت پاسخ دهید."},{"de":"Wir wollen den Termin möglichst bald festlegen.","en":"We want to set the date as soon as possible.","ru":"Мы хотим назначить дату как можно скорее.","vi":"Chúng tôi muốn ấn định ngày càng sớm càng tốt.","fa":"ما می خواهیم تاریخ را در اسرع وقت تعیین کنیم."},{"de":"Iss möglichst viel Obst und Gemüse.","en":"Eat as much fruit and vegetables as possible.","ru":"Ешьте как можно больше фруктов и овощей.","vi":"Ăn càng nhiều trái cây và rau quả càng tốt.","fa":"تا حد امکان میوه و سبزیجات مصرف کنید."}]},{"word":"die Möhre","en":"carrot","ru":"морковь","vi":"củ cà rốt","fa":"هویج","examples":[{"de":"Sie schneidet Möhren für den Salat.","en":"She cuts carrots for the salad.","ru":"Она режет морковь для салата.","vi":"Cô ấy cắt nhỏ cà rốt để làm món salad.","fa":"او هویج را برای سالاد خرد می کند."},{"de":"Kaninchen fressen gern Möhren.","en":"Rabbits like to eat carrots.","ru":"Кролики любят есть морковь.","vi":"Rabbits like to eat carrots.","fa":"خرگوش ها دوست دارند هویج بخورند."}]},{"word":"der Moment","en":"moment","ru":"момент","vi":"khoảnh khắc","fa":"لحظه","examples":[{"de":"Einen Moment bitte, ich komme gleich.","en":"One moment please, I'll be right there.","ru":"Одну минутку, я сейчас подойду.","vi":"Chỉ một lát thôi, tôi sẽ đến ngay.","fa":"فقط یک لحظه، من همان جا خواهم بود."},{"de":"In diesem Moment klingelte das Telefon.","en":"At that moment the phone rang.","ru":"В этот момент зазвонил телефон.","vi":"In dieem Moment klingelte das Telefon.","fa":"در همان لحظه تلفن زنگ خورد."}]},{"word":"die Monarchie","en":"monarchy","ru":"монархия","vi":"chế độ quân chủ","fa":"سلطنت","examples":[{"de":"In einer konstitutionellen Monarchie regiert das Parlament.","en":"In a constitutional monarchy, parliament governs.","ru":"В конституционной монархии правит парламент.","vi":"Trong chế độ quân chủ lập hiến, quốc hội cai trị.","fa":"در سلطنت مشروطه، پارلمان حکومت می کند."},{"de":"Frankreich schaffte die Monarchie während der Revolution ab.","en":"France abolished the monarchy during the revolution.","ru":"Франция упразднила монархию во время революции.","vi":"Pháp bãi bỏ chế độ quân chủ trong cuộc cách mạng.","fa":"فرانسه در جریان انقلاب سلطنت را لغو کرد."},{"de":"In der absoluten Monarchie besaß der König die gesamte Macht.","en":"In an absolute monarchy the king held all the power.","ru":"При абсолютной монархии вся власть принадлежала королю.","vi":"Trong chế độ quân chủ tuyệt đối, nhà vua có mọi quyền lực.","fa":"در یک سلطنت مطلقه، پادشاه تمام قدرت را در اختیار داشت."}]},{"word":"der Mond","en":"moon","ru":"луна","vi":"mặt trăng","fa":"ماه","examples":[{"de":"Heute Nacht ist der Mond besonders hell.","en":"Tonight the moon is especially bright.","ru":"Сегодня ночью луна особенно яркая.","vi":"Đêm nay trăng đặc biệt sáng.","fa":"امشب ماه بسیار روشن است."},{"de":"Der Mond bewegt sich um die Erde.","en":"The moon moves around the earth.","ru":"Луна вращается вокруг Земли.","vi":"Mặt trăng chuyển động quanh trái đất.","fa":"ماه در اطراف زمین حرکت می کند."}]},{"word":"die Mondfinsternis","en":"lunar eclipse","ru":"лунное затмение","vi":"nguyệt thực","fa":"the lunar eclipse","examples":[{"de":"Bei einer Mondfinsternis liegt die Erde zwischen Sonne und Mond.","en":"During a lunar eclipse the Earth lies between the Sun and the Moon.","ru":"При лунном затмении Земля находится между Солнцем и Луной.","vi":"Khi xảy ra nguyệt thực, Trái đất nằm giữa mặt trời và mặt trăng.","fa":"در طول ماه گرفتگی، زمین بین خورشید و ماه قرار می گیرد."},{"de":"Der Mond färbte sich während der Mondfinsternis rötlich.","en":"The Moon turned reddish during the lunar eclipse.","ru":"Во время лунного затмения Луна окрасилась в красноватый цвет.","vi":"Mặt trăng chuyển sang màu đỏ khi nguyệt thực.","fa":"ماه در جریان ماه گرفتگی قرمز شد."},{"de":"Eine Mondfinsternis dauert oft länger als eine Sonnenfinsternis.","en":"A lunar eclipse often lasts longer than a solar eclipse.","ru":"Лунное затмение часто длится дольше солнечного.","vi":"Nguyệt thực thường kéo dài hơn nhật thực.","fa":"یک ماه گرفتگی اغلب بیشتر از خورشید گرفتگی طول می کشد."}]},{"word":"die Mondlandung","en":"Moon landing","ru":"высадка на Луну, лунная посадка","vi":"cuộc đổ bộ lên mặt trăng","fa":"فرود ماه","examples":[{"de":"Die erste Mondlandung fand 1969 statt.","en":"The first Moon landing took place in 1969.","ru":"Первая высадка на Луну состоялась в 1969 году.","vi":"Cuộc đổ bộ lên mặt trăng đầu tiên diễn ra vào năm 1969.","fa":"اولین فرود روی ماه در سال 1969 انجام شد."},{"de":"Millionen Menschen sahen die Mondlandung im Fernsehen.","en":"Millions of people watched the Moon landing on television.","ru":"Миллионы людей смотрели высадку на Луну по телевизору.","vi":"Hàng triệu người đã nhìn thấy mặt trăng hạ cánh trên truyền hình.","fa":"میلیون ها نفر فرود ماه را در تلویزیون دیدند."},{"de":"Die Mondlandung war ein großer Schritt für die Menschheit.","en":"The Moon landing was a great step for mankind.","ru":"Высадка на Луну была большим шагом для человечества.","vi":"Cuộc đổ bộ lên mặt trăng là một bước tiến lớn của nhân loại.","fa":"فرود بر ماه گام بزرگی برای بشریت بود."}]},{"word":"der Mondschein","en":"moonlight","ru":"лунный свет","vi":"ánh trăng","fa":"the moonshine","examples":[{"de":"Wir spazierten im Mondschein durch den Park.","en":"We strolled through the park in the moonlight.","ru":"Мы гуляли по парку в лунном свете.","vi":"Chúng tôi đi dạo trong công viên dưới ánh trăng.","fa":"در پارک زیر نور مهتاب قدم زدیم."},{"de":"Der See glänzte silbern im Mondschein.","en":"The lake shone silver in the moonlight.","ru":"Озеро серебрилось в лунном свете.","vi":"Mặt hồ lấp lánh ánh bạc dưới ánh trăng.","fa":"دریاچه در نور ماه نقره ای می درخشید."},{"de":"Bei Mondschein kann man auch ohne Lampe etwas erkennen.","en":"In the moonlight you can make things out even without a lamp.","ru":"В лунном свете можно кое-что различить даже без лампы.","vi":"Dưới ánh trăng bạn có thể nhìn thấy thứ gì đó ngay cả khi không có đèn.","fa":"در نور مهتاب حتی بدون لامپ هم می توانید چیزی را ببینید."}]},{"word":"der Monitor","en":"monitor (screen)","ru":"монитор (экран)","vi":"màn hình","fa":"مانیتور","examples":[{"de":"Der Monitor meines Computers ist kaputt.","en":"My computer's monitor is broken.","ru":"Монитор моего компьютера сломан.","vi":"My computer's monitor is broken.","fa":"مانیتور کامپیوترم خرابه"},{"de":"Sie schaut den ganzen Tag auf den Monitor.","en":"She looks at the monitor all day.","ru":"Она весь день смотрит на монитор.","vi":"Cô ấy nhìn vào màn hình cả ngày.","fa":"تمام روز به مانیتور نگاه می کند."}]},{"word":"der Most","en":"must, cider (young fruit juice)","ru":"молодое фруктовое вино, сидр (свежий фруктовый сок)","vi":"điều phải","fa":"باید","examples":[{"de":"Im Herbst pressen die Bauern Most aus Äpfeln.","en":"In autumn the farmers press must from apples.","ru":"Осенью крестьяне выжимают сок из яблок.","vi":"Vào mùa thu, nông dân ép rượu táo.","fa":"در پاییز، کشاورزان سیب سیب را فشار می دهند."},{"de":"Der frische Most schmeckt süß und ein wenig herb.","en":"The fresh must tastes sweet and a little tart.","ru":"Свежий фруктовый сок сладкий и немного терпкий.","vi":"Tươi phải có vị ngọt và hơi chua.","fa":"ماست تازه طعم شیرین و کمی ترش دارد."},{"de":"In Süddeutschland trinkt man gern Most.","en":"In southern Germany people like to drink cider.","ru":"На юге Германии любят пить сидр.","vi":"Ở miền nam nước Đức người ta thích uống rượu cần.","fa":"در جنوب آلمان، مردم به نوشیدن مشروب علاقه دارند."}]},{"word":"motivieren","en":"to motivate","ru":"мотивировать","vi":"động viên","fa":"ایجاد انگیزه","examples":[{"de":"Ein guter Lehrer kann seine Schüler motivieren.","en":"A good teacher can motivate his pupils.","ru":"Хороший учитель умеет мотивировать своих учеников.","vi":"Một giáo viên giỏi có thể động viên học sinh của mình.","fa":"یک معلم خوب می تواند در دانش آموزان خود انگیزه ایجاد کند."},{"de":"Lob motiviert mich mehr als Geld.","en":"Praise motivates me more than money.","ru":"Похвала мотивирует меня больше, чем деньги.","vi":"Lời khen ngợi thúc đẩy tôi nhiều hơn tiền bạc.","fa":"تمجید بیشتر از پول به من انگیزه می دهد."},{"de":"Sie versucht, ihr Team jeden Tag neu zu motivieren.","en":"She tries to motivate her team afresh every day.","ru":"Она каждый день заново пытается мотивировать свою команду.","vi":"Cô ấy cố gắng động viên nhóm của mình mỗi ngày.","fa":"او سعی می کند هر روز به تیم خود انگیزه دهد."}]},{"word":"der Motor","en":"engine, motor","ru":"двигатель, мотор","vi":"động cơ","fa":"موتور","examples":[{"de":"Der Motor des Autos macht ein komisches Geräusch.","en":"The car's engine is making a strange noise.","ru":"Двигатель машины издаёт странный звук.","vi":"Động cơ xe phát ra tiếng động lạ.","fa":"موتور ماشین صدای عجیبی می دهد."},{"de":"Dieses Boot hat einen sehr starken Motor.","en":"This boat has a very powerful motor.","ru":"У этой лодки очень мощный мотор.","vi":"Chiếc thuyền này có động cơ rất mạnh.","fa":"این قایق موتور بسیار قدرتمندی دارد."}]},{"word":"das Motorrad","en":"motorcycle","ru":"мотоцикл","vi":"chiếc xe máy","fa":"موتور سیکلت","examples":[{"de":"Er fährt jeden Tag mit dem Motorrad zur Arbeit.","en":"He rides his motorcycle to work every day.","ru":"Он каждый день ездит на работу на мотоцикле.","vi":"Anh ấy đi xe máy đi làm hàng ngày.","fa":"او هر روز با موتورش به محل کارش می رود."},{"de":"Ein neues Motorrad ist ziemlich teuer.","en":"A new motorcycle is quite expensive.","ru":"Новый мотоцикл довольно дорогой.","vi":"Một chiếc xe máy mới khá đắt tiền.","fa":"یک موتور سیکلت جدید بسیار گران است."}]},{"word":"müde","en":"tired","ru":"усталый","vi":"mệt mỏi","fa":"خسته","examples":[{"de":"Nach der Arbeit bin ich immer sehr müde.","en":"After work I am always very tired.","ru":"После работы я всегда очень устаю.","vi":"Nach der Arbeit bin ich immer sehr müde.","fa":"من همیشه بعد از کار خیلی خسته هستم."},{"de":"Das Kind wurde müde und schlief im Auto ein.","en":"The child got tired and fell asleep in the car.","ru":"Ребёнок устал и уснул в машине.","vi":"Đứa trẻ mệt mỏi và ngủ thiếp đi trong xe.","fa":"کودک خسته شد و در ماشین خوابش برد."}]},{"word":"das Müesli","en":"muesli (Swiss spelling)","ru":"мюсли (швейцарское написание)","vi":"muesli","fa":"موسلی","examples":[{"de":"Zum Frühstück esse ich gern ein Müesli mit Joghurt.","en":"For breakfast I like to eat muesli with yoghurt.","ru":"На завтрак я люблю есть мюсли с йогуртом.","vi":"Bữa sáng tôi thích ăn muesli với sữa chua.","fa":"برای صبحانه دوست دارم موسلی با ماست بخورم."},{"de":"In der Schweiz schreibt man Müesli mit einem e.","en":"In Switzerland muesli is spelt with an e.","ru":"В Швейцарии мюсли пишут через «e» (Müesli).","vi":"Ở Thụy Sĩ, muesli được đánh vần bằng chữ e.","fa":"در سوئیس، موسلی با e نوشته می شود."},{"de":"Das Müesli enthält Haferflocken, Nüsse und Früchte.","en":"The muesli contains oats, nuts and fruit.","ru":"В мюсли есть овсяные хлопья, орехи и фрукты.","vi":"Muesli có chứa yến mạch, các loại hạt và trái cây.","fa":"موسلی حاوی تکه های جو دوسر، آجیل و میوه است."}]},{"word":"das Müesli/Müsli","en":"muesli","ru":"мюсли","vi":"muesli/muesli","fa":"موسلی / موسلی","examples":[{"de":"Zum Frühstück esse ich meistens Müsli mit Joghurt.","en":"For breakfast I mostly eat muesli with yogurt.","ru":"На завтрак я обычно ем мюсли с йогуртом.","vi":"Tôi thường ăn muesli với sữa chua vào bữa sáng.","fa":"من معمولا صبحانه موسلی را با ماست میخورم."},{"de":"Sie mischt Nüsse und Obst in ihr Müsli.","en":"She mixes nuts and fruit into her muesli.","ru":"Она добавляет орехи и фрукты в свои мюсли.","vi":"Cô trộn các loại hạt và trái cây vào muesli của mình.","fa":"او آجیل و میوه را در موسلی خود مخلوط می کند."}]},{"word":"die Mühe","en":"effort, trouble","ru":"усилие, труд, хлопоты","vi":"nỗ lực","fa":"تلاش","examples":[{"de":"Er gab sich große Mühe, die Prüfung zu bestehen.","en":"He made a great effort to pass the exam.","ru":"Он приложил большие усилия, чтобы сдать экзамен.","vi":"Anh ấy đã cố gắng hết sức để vượt qua kỳ thi.","fa":"برای قبولی در امتحان تلاش زیادی کرد."},{"de":"Vielen Dank für Ihre Mühe!","en":"Thank you very much for your trouble!","ru":"Большое спасибо за ваши старания!","vi":"Cảm ơn bạn rất nhiều vì nỗ lực của bạn!","fa":"از تلاش شما بسیار سپاسگزارم!"}]},{"word":"die Mühle","en":"a mill (a building or machine for grinding grain)","ru":"мельница (здание или машина для помола зерна)","vi":"nhà máy","fa":"the mill","examples":[{"de":"In der alten Mühle mahlt der Müller das Mehl.","en":"In the old mill the miller grinds the flour.","ru":"На старой мельнице мельник мелет муку.","vi":"Người thợ xay xay bột trong cối xay cũ.","fa":"آسیاب آرد را در آسیاب قدیمی آسیاب می کند."},{"de":"Am Fluss steht noch eine alte Mühle aus Holz.","en":"By the river there still stands an old wooden mill.","ru":"У реки всё ещё стоит старая деревянная мельница.","vi":"Bên bờ sông vẫn còn một cối xay gỗ cũ.","fa":"هنوز یک آسیاب چوبی قدیمی در کنار رودخانه وجود دارد."},{"de":"Die Mühle wird heute mit Wasserkraft angetrieben.","en":"The mill is driven by water power today.","ru":"Сегодня мельница приводится в движение силой воды.","vi":"Ngày nay nhà máy chạy bằng năng lượng nước.","fa":"امروزه این آسیاب با نیروی آب کار می کند."}]},{"word":"der Müll","en":"garbage, trash","ru":"мусор","vi":"rác","fa":"زباله","examples":[{"de":"Bring bitte den Müll nach draußen.","en":"Please take the garbage outside.","ru":"Вынеси, пожалуйста, мусор.","vi":"Hãy mang rác ra ngoài.","fa":"لطفا زباله ها را بیرون ببرید."},{"de":"Wir trennen unseren Müll in Papier, Glas und Plastik.","en":"We separate our trash into paper, glass, and plastic.","ru":"Мы сортируем мусор на бумагу, стекло и пластик.","vi":"Chúng tôi phân loại rác thải thành giấy, thủy tinh và nhựa.","fa":"زباله های خود را به کاغذ، شیشه و پلاستیک جدا می کنیم."}]},{"word":"die Müllabfuhr","en":"refuse collection, bin collection (service)","ru":"вывоз мусора (служба)","vi":"việc xử lý rác thải","fa":"دفع زباله","examples":[{"de":"Die Müllabfuhr kommt bei uns jeden Mittwoch.","en":"The refuse collection comes to us every Wednesday.","ru":"Мусоровоз приезжает к нам каждую среду.","vi":"Việc thu gom rác của chúng tôi diễn ra vào thứ Tư hàng tuần.","fa":"جمع آوری زباله ما هر چهارشنبه می آید."},{"de":"Stell bitte die Tonne raus, gleich kommt die Müllabfuhr.","en":"Please put the bin out, the refuse collection is coming soon.","ru":"Выставь, пожалуйста, бак, скоро приедет мусоровоз.","vi":"Vui lòng bỏ thùng rác ra, việc thu gom rác sẽ sớm đến.","fa":"لطفا سطل زباله را بیرون بگذارید، جمع آوری زباله به زودی خواهد آمد."},{"de":"An Feiertagen fällt die Müllabfuhr manchmal aus.","en":"On public holidays the refuse collection is sometimes cancelled.","ru":"В праздники вывоз мусора иногда отменяют.","vi":"Việc thu gom rác đôi khi bị hủy bỏ vào các ngày lễ.","fa":"جمع آوری زباله گاهی اوقات در روزهای تعطیل لغو می شود."}]},{"word":"der Müller","en":"a miller (someone who grinds grain into flour)","ru":"мельник (тот, кто мелет зерно в муку)","vi":"người thợ xay","fa":"the miller","examples":[{"de":"Der Müller Müller mahlt mühevoll Mehl.","en":"The miller Müller laboriously grinds flour.","ru":"Мельник Мюллер с трудом мелет муку.","vi":"Người thợ xay Müller miệt mài xay bột.","fa":"آسیاب مولر با زحمت آرد را آسیاب می کند."},{"de":"Der Müller stand jeden Morgen früh in der Mühle.","en":"The miller stood in the mill early every morning.","ru":"Каждое утро мельник рано вставал у мельницы.","vi":"Người thợ xay có mặt ở nhà máy vào mỗi buổi sáng sớm.","fa":"آسیابان هر روز صبح زود در آسیاب بود."},{"de":"Im Märchen verspricht der Müller dem König großen Reichtum.","en":"In the fairy tale the miller promises the king great riches.","ru":"В сказке мельник обещает королю большое богатство.","vi":"Trong câu chuyện cổ tích, người thợ xay hứa hẹn với nhà vua sự giàu có lớn lao.","fa":"در افسانه، آسیابان به پادشاه وعده ثروت فراوان می دهد."}]},{"word":"die Mülltonne","en":"rubbish bin, dustbin","ru":"мусорный бак, мусорное ведро","vi":"thùng rác","fa":"سطل زباله","examples":[{"de":"Die Mülltonne wird jeden Donnerstag geleert.","en":"The rubbish bin is emptied every Thursday.","ru":"Мусорный бак опустошают каждый четверг.","vi":"Thùng rác được dọn sạch vào thứ Năm hàng tuần.","fa":"سطل زباله هر پنجشنبه تخلیه می شود."},{"de":"Bring bitte den Sack zur Mülltonne im Hof.","en":"Please take the bag to the bin in the yard.","ru":"Отнеси, пожалуйста, пакет к мусорному баку во дворе.","vi":"Hãy mang túi vào thùng rác trong sân.","fa":"لطفا کیسه را به سطل زباله در حیاط ببرید."},{"de":"Die graue Mülltonne ist für den Restmüll.","en":"The grey bin is for general waste.","ru":"Серый бак предназначен для общих отходов.","vi":"Thùng rác màu xám dùng để đựng rác thải còn sót lại.","fa":"سطل زباله خاکستری برای زباله های باقی مانده است."}]},{"word":"die Müllvermeidung","en":"waste avoidance","ru":"сокращение мусора, предотвращение образования мусора","vi":"phòng chống lãng phí","fa":"پیشگیری از زباله","examples":[{"de":"Müllvermeidung beginnt schon beim Einkaufen.","en":"Waste avoidance begins already when shopping.","ru":"Сокращение мусора начинается уже при покупках.","vi":"Tránh lãng phí bắt đầu bằng việc mua sắm.","fa":"پرهیز از اسراف با خرید شروع می شود."},{"de":"Mit Stofftaschen leisten wir einen Beitrag zur Müllvermeidung.","en":"With cloth bags we contribute to waste avoidance.","ru":"С тканевыми сумками мы вносим вклад в сокращение мусора.","vi":"Với túi vải chúng tôi góp phần tránh lãng phí.","fa":"با کیسه های پارچه ای کمکی به جلوگیری از ضایعات می کنیم."},{"de":"Die Stadt setzt verstärkt auf Müllvermeidung.","en":"The city is increasingly focusing on waste avoidance.","ru":"Город всё активнее делает ставку на сокращение мусора.","vi":"Thành phố ngày càng chú trọng đến việc ngăn chặn rác thải.","fa":"تمرکز شهر به طور فزاینده ای بر پیشگیری از زباله است."}]},{"word":"die Multiplikation","en":"multiplication","ru":"умножение","vi":"phép nhân","fa":"ضرب","examples":[{"de":"Die Multiplikation lernt man mit dem Einmaleins.","en":"You learn multiplication with the times tables.","ru":"Умножение учат по таблице умножения.","vi":"Bạn học phép nhân bằng bảng cửu chương.","fa":"ضرب را با استفاده از جداول ضرب یاد می گیرید."},{"de":"Die Multiplikation von 6 und 7 ergibt 42.","en":"The multiplication of 6 and 7 gives 42.","ru":"Умножение 6 и 7 даёт 42.","vi":"Nhân 6 và 7 bằng 42.","fa":"ضرب 6 و 7 برابر با 42 می شود."},{"de":"Eine Multiplikation kann man als wiederholte Addition verstehen.","en":"A multiplication can be understood as repeated addition.","ru":"Умножение можно понимать как повторное сложение.","vi":"Phép nhân có thể được hiểu là phép cộng lặp đi lặp lại.","fa":"ضرب را می توان به صورت جمع مکرر درک کرد."}]},{"word":"der Mund","en":"mouth","ru":"рот","vi":"cái miệng","fa":"دهان","examples":[{"de":"Sie öffnete den Mund, um etwas zu sagen.","en":"She opened her mouth to say something.","ru":"Она открыла рот, чтобы что-то сказать.","vi":"Cô mở miệng định nói điều gì đó.","fa":"دهانش را باز کرد تا چیزی بگوید."},{"de":"Sprich bitte nicht mit vollem Mund.","en":"Please don't talk with your mouth full.","ru":"Пожалуйста, не говори с набитым ртом.","vi":"Làm ơn đừng nói khi miệng đầy thức ăn.","fa":"لطفا با دهان پر صحبت نکنید"}]},{"word":"mündlich","en":"oral, verbal","ru":"устный","vi":"bằng miệng","fa":"دهانی","examples":[{"de":"Die mündliche Prüfung findet nächste Woche statt.","en":"The oral exam takes place next week.","ru":"Устный экзамен состоится на следующей неделе.","vi":"Kỳ thi vấn đáp sẽ diễn ra vào tuần tới.","fa":"آزمون شفاهی هفته آینده برگزار خواهد شد."},{"de":"Wir haben das nur mündlich vereinbart.","en":"We agreed that only verbally.","ru":"Мы договорились об этом только устно.","vi":"Chúng tôi chỉ đồng ý bằng lời nói.","fa":"ما فقط شفاهی توافق کردیم."},{"de":"Bei der Note zählt auch die mündliche Mitarbeit.","en":"Oral participation also counts towards the grade.","ru":"Устное участие тоже учитывается при выставлении оценки.","vi":"Việc tham gia miệng cũng được tính vào điểm.","fa":"مشارکت شفاهی نیز به عنوان نمره محسوب می شود."}]},{"word":"die Münze","en":"coin","ru":"монета","vi":"đồng xu","fa":"سکه","examples":[{"de":"Ich habe keine Münzen für den Parkautomaten.","en":"I don't have any coins for the parking meter.","ru":"У меня нет монет для парковочного автомата.","vi":"Tôi không có xu cho máy đỗ xe.","fa":"برای ماشین پارکینگ سکه ندارم."},{"de":"Er sammelt alte Münzen aus verschiedenen Ländern.","en":"He collects old coins from different countries.","ru":"Он коллекционирует старые монеты из разных стран.","vi":"Anh ấy sưu tập những đồng xu cổ từ các quốc gia khác nhau.","fa":"او سکه های قدیمی را از کشورهای مختلف جمع آوری می کند."}]},{"word":"das Museum","en":"museum","ru":"музей","vi":"bảo tàng","fa":"موزه","examples":[{"de":"Am Wochenende besuchen wir das Kunstmuseum.","en":"On the weekend we visit the art museum.","ru":"В выходные мы посещаем художественный музей.","vi":"Vào cuối tuần chúng tôi ghé thăm bảo tàng nghệ thuật.","fa":"آخر هفته از موزه هنر دیدن می کنیم."},{"de":"Der Eintritt ins Museum ist für Kinder kostenlos.","en":"Admission to the museum is free for children.","ru":"Вход в музей для детей бесплатный.","vi":"Vào bảo tàng miễn phí cho trẻ em.","fa":"ورود به موزه برای کودکان رایگان است."}]},{"word":"die Musik","en":"music","ru":"музыка","vi":"âm nhạc","fa":"موسیقی","examples":[{"de":"Ich höre gern klassische Musik beim Lernen.","en":"I like listening to classical music while studying.","ru":"Я люблю слушать классическую музыку во время учёбы.","vi":"Tôi thích nghe nhạc cổ điển trong khi học.","fa":"من دوست دارم در حین مطالعه به موسیقی کلاسیک گوش کنم."},{"de":"Auf dem Fest spielte eine Band live Musik.","en":"At the party, a band played live music.","ru":"На празднике группа играла живую музыку.","vi":"Một ban nhạc chơi nhạc sống tại lễ hội.","fa":"یک گروه موسیقی زنده در این جشنواره پخش کردند."}]},{"word":"musikalisch","en":"musical","ru":"музыкальный","vi":"về mặt âm nhạc","fa":"از نظر موسیقی","examples":[{"de":"Ihre ganze Familie ist sehr musikalisch.","en":"Her whole family is very musical.","ru":"Вся её семья очень музыкальна.","vi":"Cả gia đình cô đều rất yêu âm nhạc.","fa":"تمام خانواده او بسیار موزیکال هستند."},{"de":"Schon als Kind zeigte er großes musikalisches Talent.","en":"Even as a child he showed great musical talent.","ru":"Ещё ребёнком он проявил большой музыкальный талант.","vi":"Ngay từ khi còn nhỏ, anh đã bộc lộ tài năng âm nhạc tuyệt vời.","fa":"او حتی در کودکی استعداد زیادی در موسیقی از خود نشان داد."},{"de":"Der Abend bot ein abwechslungsreiches musikalisches Programm.","en":"The evening offered a varied musical programme.","ru":"Вечер предложил разнообразную музыкальную программу.","vi":"Buổi tối cung cấp một chương trình âm nhạc đa dạng.","fa":"این شب یک برنامه موسیقی متنوع ارائه کرد."}]},{"word":"der Musiker","en":"musician (male)","ru":"музыкант (мужчина)","vi":"nhạc sĩ","fa":"نوازنده","examples":[{"de":"Mein Bruder ist Musiker und spielt in einer Band.","en":"My brother is a musician and plays in a band.","ru":"Мой брат музыкант, он играет в группе.","vi":"Anh trai tôi là một nhạc sĩ và chơi trong một ban nhạc.","fa":"برادرم نوازنده است و در یک گروه می نوازد."},{"de":"Der Musiker übt jeden Tag mehrere Stunden Klavier.","en":"The musician practises the piano for several hours every day.","ru":"Музыкант каждый день играет на фортепиано по несколько часов.","vi":"Nhạc sĩ luyện tập piano vài giờ mỗi ngày.","fa":"نوازنده هر روز چندین ساعت پیانو تمرین می کند."},{"de":"Viele Musiker verdienen leider nicht viel Geld.","en":"Unfortunately many musicians don't earn much money.","ru":"К сожалению, многие музыканты зарабатывают немного.","vi":"Thật không may, nhiều nhạc sĩ không kiếm được nhiều tiền.","fa":"متأسفانه بسیاری از نوازندگان درآمد چندانی ندارند."}]},{"word":"die Musikerin","en":"musician (female)","ru":"музыкантша (женщина)","vi":"nhạc sĩ","fa":"نوازنده","examples":[{"de":"Die Musikerin spielt wunderbar Geige.","en":"The musician plays the violin wonderfully.","ru":"Музыкантша чудесно играет на скрипке.","vi":"Nhạc sĩ chơi violin tuyệt vời.","fa":"نوازنده به طرز شگفت انگیزی ویولن می نوازد."},{"de":"Als junge Musikerin trat sie in vielen Konzerten auf.","en":"As a young musician she performed in many concerts.","ru":"Молодой музыкантшей она выступала во многих концертах.","vi":"Là một nhạc sĩ trẻ, cô đã biểu diễn trong nhiều buổi hòa nhạc.","fa":"به عنوان یک نوازنده جوان در کنسرت های زیادی اجرا کرد."},{"de":"Die Musikerin schreibt ihre Lieder selbst.","en":"The musician writes her songs herself.","ru":"Музыкантша сама пишет свои песни.","vi":"Nhạc sĩ viết những bài hát của riêng mình.","fa":"این نوازنده آهنگ های خود را می نویسد."}]},{"word":"der Muskel","en":"muscle","ru":"мышца","vi":"cơ bắp","fa":"ماهیچه","examples":[{"de":"Nach dem Training tun mir die Muskeln weh.","en":"After training, my muscles hurt.","ru":"После тренировки у меня болят мышцы.","vi":"Cơ bắp của tôi bị đau sau khi tập luyện.","fa":"بعد از تمرین عضلاتم درد می کند."},{"de":"Regelmäßiger Sport stärkt die Muskeln.","en":"Regular exercise strengthens the muscles.","ru":"Регулярные занятия спортом укрепляют мышцы.","vi":"Tập thể dục thường xuyên giúp tăng cường cơ bắp.","fa":"ورزش منظم عضلات را تقویت می کند."}]},{"word":"die Muskulatur","en":"musculature","ru":"мускулатура","vi":"cơ bắp","fa":"ماهیچه ها","examples":[{"de":"Yoga kräftigt die tiefe Muskulatur des Rückens.","en":"Yoga strengthens the deep musculature of the back.","ru":"Йога укрепляет глубокую мускулатуру спины.","vi":"Yoga tăng cường cơ bắp sâu của lưng.","fa":"یوگا ماهیچه های عمیق کمر را تقویت می کند."},{"de":"Eine starke Muskulatur stützt die Wirbelsäule.","en":"Strong musculature supports the spine.","ru":"Сильная мускулатура поддерживает позвоночник.","vi":"Cơ bắp khỏe mạnh hỗ trợ cột sống.","fa":"ماهیچه های قوی از ستون فقرات حمایت می کنند."},{"de":"Nach dem Sport ist meine Muskulatur leicht müde.","en":"After exercise my musculature is slightly tired.","ru":"После спорта моя мускулатура слегка устала.","vi":"Sau khi tập luyện, cơ bắp của tôi dễ bị mỏi.","fa":"بعد از ورزش، عضلاتم به راحتی خسته می شوند."}]},{"word":"das Müsli","en":"muesli","ru":"мюсли","vi":"muesli","fa":"موسلی","examples":[{"de":"Morgens esse ich meistens ein Müsli mit Milch.","en":"In the mornings I usually eat muesli with milk.","ru":"По утрам я обычно ем мюсли с молоком.","vi":"Buổi sáng tôi thường ăn ngũ cốc với sữa.","fa":"صبح ها معمولاً غلات را با شیر می خورم."},{"de":"Dieses Müsli ist mir leider zu süß.","en":"This muesli is unfortunately too sweet for me.","ru":"Эти мюсли, к сожалению, для меня слишком сладкие.","vi":"Thật không may, muesli này quá ngọt đối với tôi.","fa":"متاسفانه این موسلی برای من خیلی شیرین است."},{"de":"Im Supermarkt gibt es viele verschiedene Sorten Müsli.","en":"In the supermarket there are many different kinds of muesli.","ru":"В супермаркете много разных сортов мюсли.","vi":"Có rất nhiều loại muesli khác nhau trong siêu thị.","fa":"انواع مختلفی از موسلی در سوپرمارکت وجود دارد."}]},{"word":"müssen","en":"must, to have to","ru":"быть должным, обязан","vi":"phải","fa":"باید","examples":[{"de":"Ich muss morgen früh aufstehen.","en":"I have to get up early tomorrow.","ru":"Мне нужно завтра рано встать.","vi":"Ngày mai tôi phải dậy sớm.","fa":"فردا باید زود بیدار بشم"},{"de":"Wir müssen die Miete bis zum Ersten bezahlen.","en":"We have to pay the rent by the first of the month.","ru":"Мы должны заплатить арендную плату до первого числа.","vi":"Chúng tôi phải trả tiền thuê nhà vào ngày đầu tiên.","fa":"تا روز اول باید کرایه را پرداخت کنیم."}]},{"word":"das Muster","en":"pattern","ru":"закономерность, паттерн","vi":"mô hình","fa":"الگو","examples":[{"de":"In den Daten erkennen wir ein klares Muster.","en":"We recognise a clear pattern in the data.","ru":"В данных мы распознаём чёткую закономерность.","vi":"Chúng tôi thấy một mô hình rõ ràng trong dữ liệu.","fa":"ما یک الگوی واضح در داده ها می بینیم."},{"de":"Das Programm sucht nach Mustern im Verhalten der Nutzer.","en":"The program searches for patterns in the users' behaviour.","ru":"Программа ищет закономерности в поведении пользователей.","vi":"Chương trình tìm kiếm các mẫu hành vi của người dùng.","fa":"این برنامه به دنبال الگوهایی در رفتار کاربر است."},{"de":"Ein wiederkehrendes Muster kann auf einen Fehler hinweisen.","en":"A recurring pattern can point to an error.","ru":"Повторяющаяся закономерность может указывать на ошибку.","vi":"Một mẫu lặp lại có thể chỉ ra một lỗi.","fa":"یک الگوی تکرارشونده ممکن است نشان دهنده یک خطا باشد."}]},{"word":"der Mut","en":"courage","ru":"смелость, мужество","vi":"sự can đảm","fa":"شجاعت","examples":[{"de":"Es braucht Mut, seine Meinung offen zu sagen.","en":"It takes courage to say your opinion openly.","ru":"Нужна смелость, чтобы открыто высказать своё мнение.","vi":"Cần phải có can đảm để bày tỏ ý kiến của mình một cách cởi mở.","fa":"ابراز صراحت نظر خود شجاعت می خواهد."},{"de":"Sie fasste all ihren Mut zusammen und sprang ins Wasser.","en":"She gathered all her courage and jumped into the water.","ru":"Она собрала всю свою смелость и прыгнула в воду.","vi":"Cô lấy hết can đảm và nhảy xuống nước.","fa":"تمام شهامتش را جمع کرد و پرید توی آب."}]},{"word":"mutig","en":"courageous, brave","ru":"смелый, храбрый","vi":"dũng cảm","fa":"شجاع","examples":[{"de":"Der Feuerwehrmann war sehr mutig und rettete das Kind.","en":"The firefighter was very brave and saved the child.","ru":"Пожарный был очень смелым и спас ребёнка.","vi":"Người lính cứu hỏa đã rất dũng cảm và cứu được đứa trẻ.","fa":"آتش نشان بسیار شجاع بود و کودک را نجات داد."},{"de":"Es war mutig von dir, die Wahrheit zu sagen.","en":"It was brave of you to tell the truth.","ru":"С твоей стороны было смело сказать правду.","vi":"Bạn thật dũng cảm khi nói ra sự thật.","fa":"این شجاعت شما بود که حقیقت را گفتید."}]},{"word":"die Mutter","en":"mother","ru":"мать","vi":"người mẹ","fa":"مادر","examples":[{"de":"Meine Mutter kocht jeden Sonntag ein großes Essen.","en":"My mother cooks a big meal every Sunday.","ru":"Моя мама готовит большой обед каждое воскресенье.","vi":"Mẹ tôi nấu một bữa ăn thịnh soạn vào mỗi Chủ nhật.","fa":"مادرم هر یکشنبه یک غذای بزرگ درست می کند."},{"de":"Sie ist Mutter von drei Kindern.","en":"She is the mother of three children.","ru":"Она мать троих детей.","vi":"Cô là mẹ của ba đứa trẻ.","fa":"او مادر سه فرزند است."}]},{"word":"die Muttersprache","en":"mother tongue, native language","ru":"родной язык","vi":"ngôn ngữ bản địa","fa":"زبان مادری","examples":[{"de":"Meine Muttersprache ist Spanisch, aber ich lerne Deutsch.","en":"My mother tongue is Spanish, but I'm learning German.","ru":"Мой родной язык — испанский, но я учу немецкий.","vi":"Ngôn ngữ mẹ đẻ của tôi là tiếng Tây Ban Nha, nhưng tôi đang học tiếng Đức.","fa":"زبان مادری من اسپانیایی است، اما در حال یادگیری آلمانی هستم."},{"de":"In seiner Muttersprache kann er sich am besten ausdrücken.","en":"In his mother tongue he can express himself best.","ru":"На родном языке он выражается лучше всего.","vi":"Anh ấy có thể thể hiện bản thân tốt nhất bằng ngôn ngữ mẹ đẻ của mình.","fa":"او می تواند خود را به بهترین نحو به زبان مادری خود بیان کند."},{"de":"Welche Muttersprache sprichst du zu Hause?","en":"Which mother tongue do you speak at home?","ru":"На каком родном языке вы говорите дома?","vi":"Bạn nói ngôn ngữ mẹ đẻ nào ở nhà?","fa":"به چه زبان مادری در خانه صحبت می کنید؟"}]},{"word":"nach","en":"after; to(wards) (a place)","ru":"после; в, к (направление)","vi":"sau","fa":"بعد از","examples":[{"de":"Nach der Arbeit gehe ich meistens einkaufen.","en":"After work I usually go shopping.","ru":"После работы я обычно хожу за покупками.","vi":"Sau giờ làm việc tôi thường đi mua sắm.","fa":"بعد از کار معمولاً به خرید می روم."},{"de":"Wir fliegen nächste Woche nach Spanien.","en":"We are flying to Spain next week.","ru":"На следующей неделе мы летим в Испанию.","vi":"Chúng tôi sẽ bay đến Tây Ban Nha vào tuần tới.","fa":"هفته آینده به اسپانیا پرواز می کنیم."}]},{"word":"der Nachbar","en":"neighbor","ru":"сосед","vi":"người hàng xóm","fa":"همسایه","examples":[{"de":"Unser Nachbar ist sehr freundlich und hilfsbereit.","en":"Our neighbor is very friendly and helpful.","ru":"Наш сосед очень дружелюбный и отзывчивый.","vi":"Hàng xóm của chúng tôi rất thân thiện và hữu ích.","fa":"همسایه ما بسیار صمیمی و مفید است."},{"de":"Ich habe meinen neuen Nachbarn noch nicht kennengelernt.","en":"I haven't met my new neighbor yet.","ru":"Я ещё не познакомился со своим новым соседом.","vi":"Tôi vẫn chưa gặp người hàng xóm mới của mình.","fa":"من هنوز همسایه جدیدم را ندیده ام."}]},{"word":"die Nachbarschaft","en":"neighbourhood","ru":"соседство; район","vi":"khu phố","fa":"محله","examples":[{"de":"In unserer Nachbarschaft kennt jeder jeden.","en":"In our neighbourhood everyone knows everyone.","ru":"В нашем районе все знают друг друга.","vi":"Trong khu phố của chúng tôi mọi người đều biết nhau.","fa":"در محله ما همه همه را می شناسند."},{"de":"Die Nachbarschaft hat sich in den letzten Jahren verändert.","en":"The neighbourhood has changed in recent years.","ru":"Район изменился за последние годы.","vi":"Khu phố đã thay đổi trong những năm gần đây.","fa":"محله در سال های اخیر تغییر کرده است."}]},{"word":"nachdem","en":"after (conjunction)","ru":"после того как","vi":"sau","fa":"بعد از","examples":[{"de":"Nachdem wir gegessen hatten, gingen wir spazieren.","en":"After we had eaten, we went for a walk.","ru":"После того как мы поели, мы пошли гулять.","vi":"Ăn xong chúng tôi đi dạo.","fa":"بعد از خوردن غذا رفتیم پیاده روی."},{"de":"Nachdem sie die Prüfung bestanden hatte, feierte sie mit Freunden.","en":"After she had passed the exam, she celebrated with friends.","ru":"После того как она сдала экзамен, она отпраздновала это с друзьями.","vi":"Sau khi vượt qua kỳ thi, cô đã ăn mừng cùng bạn bè.","fa":"بعد از قبولی در امتحان، با دوستانش جشن گرفت."}]},{"word":"nachdenken","en":"to think about, to reflect (on)","ru":"размышлять, обдумывать","vi":"nghĩ","fa":"فکر کن","examples":[{"de":"Ich muss noch einmal über deinen Vorschlag nachdenken.","en":"I have to think about your suggestion once more.","ru":"Мне нужно ещё раз обдумать твоё предложение.","vi":"Tôi sẽ phải suy nghĩ lại về đề nghị của bạn.","fa":"من باید دوباره در مورد پیشنهاد شما فکر کنم."},{"de":"Er saß still da und dachte über sein Leben nach.","en":"He sat quietly and reflected on his life.","ru":"Он сидел тихо и размышлял о своей жизни.","vi":"Anh ngồi lặng im và ngẫm nghĩ về cuộc đời mình.","fa":"ساکت نشسته بود و به زندگیش فکر می کرد."}]},{"word":"nachdenklich","en":"thoughtful","ru":"задумчивый, погружённый в раздумья","vi":"chu đáo","fa":"متفکر","examples":[{"de":"Nach dem Gespräch wurde er ganz nachdenklich.","en":"After the conversation he became quite thoughtful.","ru":"После разговора он стал совсем задумчивым.","vi":"Sau cuộc trò chuyện, anh ấy trở nên rất suy nghĩ.","fa":"بعد از صحبت او بسیار متفکر شد."},{"de":"Sie sah mich nachdenklich an.","en":"She looked at me thoughtfully.","ru":"Она задумчиво посмотрела на меня.","vi":"Cô ấy nhìn tôi trầm ngâm.","fa":"متفکرانه به من نگاه کرد."},{"de":"Der Film stimmt einen nachdenklich.","en":"The film makes you thoughtful.","ru":"Фильм заставляет задуматься.","vi":"Bộ phim khiến bạn phải suy nghĩ.","fa":"فیلم آدم را به فکر وا می دارد."}]},{"word":"die Nachfrage","en":"demand","ru":"спрос","vi":"nhu cầu","fa":"تقاضا","examples":[{"de":"Die Nachfrage nach diesem Produkt ist sehr hoch.","en":"The demand for this product is very high.","ru":"Спрос на этот продукт очень высокий.","vi":"Nhu cầu về sản phẩm này rất cao.","fa":"تقاضا برای این محصول بسیار زیاد است."},{"de":"Wegen der starken Nachfrage sind die Karten schon ausverkauft.","en":"Due to strong demand, the tickets are already sold out.","ru":"Из-за высокого спроса билеты уже распроданы.","vi":"Do nhu cầu mạnh nên vé đã được bán hết.","fa":"به دلیل تقاضای زیاد، بلیط ها در حال حاضر فروخته شده است."}]},{"word":"nachhaltig","en":"sustainable","ru":"устойчивый; экологически ответственный","vi":"bền vững","fa":"پایدار","examples":[{"de":"Nachhaltiger Konsum schont die Ressourcen.","en":"Sustainable consumption conserves resources.","ru":"Ответственное потребление бережёт ресурсы.","vi":"Tiêu dùng bền vững bảo tồn tài nguyên.","fa":"مصرف پایدار باعث حفظ منابع می شود."},{"de":"Die Firma setzt auf nachhaltige Produktion.","en":"The company relies on sustainable production.","ru":"Компания делает ставку на устойчивое производство.","vi":"Công ty dựa vào sản xuất bền vững.","fa":"این شرکت بر تولید پایدار متکی است."}]},{"word":"nachher","en":"afterwards","ru":"потом, после","vi":"sau đó","fa":"پس از آن","examples":[{"de":"Wir gehen jetzt essen, nachher schauen wir einen Film.","en":"We're going to eat now, afterwards we'll watch a movie.","ru":"Сейчас мы пойдём поедим, а потом посмотрим фильм.","vi":"Bây giờ chúng ta sẽ đi ăn và sau đó chúng ta sẽ xem phim.","fa":"حالا می خوایم و بعد فیلم می بینیم."},{"de":"Ruf mich bitte nachher zurück.","en":"Please call me back afterwards.","ru":"Пожалуйста, перезвони мне потом.","vi":"Vui lòng gọi lại cho tôi sau.","fa":"لطفاً بعداً با من تماس بگیرید."}]},{"word":"die Nachhilfe","en":"tutoring, extra lessons","ru":"дополнительные занятия, репетиторство","vi":"việc dạy kèm","fa":"تدریس خصوصی","examples":[{"de":"Mein Sohn bekommt Nachhilfe in Mathematik.","en":"My son gets tutoring in mathematics.","ru":"Мой сын занимается с репетитором по математике.","vi":"Con trai tôi đang được dạy kèm môn toán.","fa":"پسرم در حال تدریس خصوصی ریاضی است."},{"de":"Sie gibt Schülern Nachhilfe in Englisch.","en":"She tutors students in English.","ru":"Она даёт ученикам дополнительные уроки английского.","vi":"Cô dạy kèm cho học sinh bằng tiếng Anh.","fa":"او به دانش آموزان آموزش زبان انگلیسی می دهد."}]},{"word":"nachreichen","en":"to submit later, to hand in subsequently","ru":"доносить, досылать (позже)","vi":"gửi sau","fa":"بعدا ارسال کنید","examples":[{"de":"Die fehlenden Unterlagen können Sie später nachreichen.","en":"You can submit the missing documents later.","ru":"Недостающие документы можно донести позже.","vi":"Bạn có thể gửi các tài liệu còn thiếu sau.","fa":"می توانید مدارک گم شده را بعدا ارسال کنید."},{"de":"Ich reiche das Attest morgen nach.","en":"I'll hand in the medical certificate tomorrow.","ru":"Я сдам справку завтра.","vi":"Ngày mai tôi sẽ nộp giấy chứng nhận.","fa":"فردا گواهینامه را ارائه می کنم."},{"de":"Bitte reichen Sie den Nachweis bis Freitag nach.","en":"Please submit the proof by Friday.","ru":"Пожалуйста, предоставьте подтверждение до пятницы.","vi":"Vui lòng gửi bằng chứng trước thứ Sáu.","fa":"لطفا تا جمعه مدرک ارسال کنید."}]},{"word":"die Nachricht","en":"message; news","ru":"сообщение; новость","vi":"tin nhắn","fa":"پیام","examples":[{"de":"Ich habe dir eine Nachricht auf dem Handy geschickt.","en":"I sent you a message on your phone.","ru":"Я отправил тебе сообщение на телефон.","vi":"Tôi đã gửi cho bạn một tin nhắn trên điện thoại di động của bạn.","fa":"با موبایلت پیام دادم"},{"de":"Im Radio hörten wir die neuesten Nachrichten.","en":"On the radio we heard the latest news.","ru":"По радио мы услышали последние новости.","vi":"Chúng tôi đã nghe tin tức mới nhất trên đài phát thanh.","fa":"آخرین اخبار را از رادیو شنیدیم."}]},{"word":"die Nachricht hinterlassen","en":"to leave a message","ru":"оставить сообщение","vi":"để lại tin nhắn","fa":"پیام را بگذارید","examples":[{"de":"Bitte hinterlassen Sie eine Nachricht nach dem Ton.","en":"Please leave a message after the tone.","ru":"Пожалуйста, оставьте сообщение после сигнала.","vi":"Vui lòng để lại lời nhắn sau tiếng chuông.","fa":"لطفا بعد از لحن پیام بگذارید."},{"de":"Er hat mir eine kurze Nachricht hinterlassen.","en":"He left me a short message.","ru":"Он оставил мне короткое сообщение.","vi":"Anh ấy để lại cho tôi một tin nhắn ngắn.","fa":"پیام کوتاهی برایم گذاشت."},{"de":"Falls niemand abnimmt, hinterlasse eine Nachricht.","en":"If nobody answers, leave a message.","ru":"Если никто не возьмёт трубку, оставь сообщение.","vi":"Nếu không có ai trả lời, hãy để lại tin nhắn.","fa":"اگر کسی جواب نداد پیام بگذارید."}]},{"word":"die Nachrichten","en":"news (broadcast); messages","ru":"новости (выпуск); сообщения","vi":"tin tức","fa":"اخبار","examples":[{"de":"Abends sehe ich immer die Nachrichten im Fernsehen.","en":"In the evening I always watch the news on television.","ru":"Вечером я всегда смотрю новости по телевизору.","vi":"Vào buổi tối tôi luôn xem tin tức trên TV.","fa":"عصرها همیشه اخبار را از تلویزیون تماشا می کنم."},{"de":"Hast du heute schon die Nachrichten gehört?","en":"Have you already heard the news today?","ru":"Ты уже слышал сегодняшние новости?","vi":"Bạn đã nghe tin tức ngày hôm nay chưa?","fa":"خبر امروز را شنیدی؟"},{"de":"Auf meinem Handy waren viele ungelesene Nachrichten.","en":"There were many unread messages on my phone.","ru":"На телефоне было много непрочитанных сообщений.","vi":"Có rất nhiều tin nhắn chưa đọc trên điện thoại của tôi.","fa":"پیام های خوانده نشده زیادی روی گوشی من بود."}]},{"word":"nachschlagen","en":"to look up (a word/information)","ru":"искать, смотреть (слово в словаре и т.п.)","vi":"tra cứu","fa":"به بالا نگاه کن","examples":[{"de":"Ich schlage das Wort im Wörterbuch nach.","en":"I look up the word in the dictionary.","ru":"Я ищу это слово в словаре.","vi":"Tôi tra từ đó trong từ điển.","fa":"کلمه را در فرهنگ لغت جستجو می کنم."},{"de":"Wenn du etwas nicht verstehst, kannst du es im Internet nachschlagen.","en":"If you don't understand something, you can look it up on the internet.","ru":"Если ты чего-то не понимаешь, ты можешь найти это в интернете.","vi":"Nếu bạn không hiểu điều gì đó, bạn có thể tra cứu trực tuyến.","fa":"اگر چیزی را متوجه نشدید، می توانید آن را به صورت آنلاین جستجو کنید."}]},{"word":"die Nachspeise","en":"dessert","ru":"десерт","vi":"món tráng miệng","fa":"دسر","examples":[{"de":"Als Nachspeise gibt es heute Schokoladenkuchen.","en":"Today's dessert is chocolate cake.","ru":"На десерт сегодня шоколадный торт.","vi":"Món tráng miệng hôm nay chúng tôi có bánh sô-cô-la.","fa":"برای دسر امروز کیک شکلاتی داریم."},{"de":"Möchten Sie noch eine Nachspeise bestellen?","en":"Would you like to order a dessert?","ru":"Хотите заказать десерт?","vi":"Bạn có muốn gọi món tráng miệng khác không?","fa":"آیا می خواهید دسر دیگری سفارش دهید؟"}]},{"word":"der Nachteil","en":"disadvantage","ru":"недостаток","vi":"điều bất lợi","fa":"ضرر","examples":[{"de":"Ein Nachteil dieser Wohnung ist der Lärm von der Straße.","en":"One disadvantage of this apartment is the noise from the street.","ru":"Один из недостатков этой квартиры — шум с улицы.","vi":"Một nhược điểm của căn hộ này là tiếng ồn từ đường phố.","fa":"از معایب این آپارتمان سر و صدای خیابان است."},{"de":"Jede Entscheidung hat Vor- und Nachteile.","en":"Every decision has advantages and disadvantages.","ru":"У каждого решения есть плюсы и минусы.","vi":"Mọi quyết định đều có ưu điểm và nhược điểm.","fa":"هر تصمیمی مزایا و معایبی دارد."}]},{"word":"der Nachthimmel","en":"night sky","ru":"ночное небо","vi":"bầu trời đêm","fa":"آسمان شب","examples":[{"de":"Der Nachthimmel war voller heller Sterne.","en":"The night sky was full of bright stars.","ru":"Ночное небо было полно ярких звёзд.","vi":"Bầu trời đêm đầy sao sáng.","fa":"آسمان شب پر از ستاره های درخشان بود."},{"de":"Vom Berg aus sieht man den Nachthimmel besonders gut.","en":"From the mountain you can see the night sky particularly well.","ru":"С горы ночное небо видно особенно хорошо.","vi":"Bạn có thể nhìn thấy bầu trời đêm đặc biệt rõ ràng từ trên núi.","fa":"شما می توانید آسمان شب را به خوبی از روی کوه مشاهده کنید."},{"de":"Sie beobachtet gern den klaren Nachthimmel.","en":"She likes to watch the clear night sky.","ru":"Она любит смотреть на ясное ночное небо.","vi":"Cô thích ngắm bầu trời đêm trong xanh.","fa":"او از تماشای آسمان صاف شب لذت می برد."}]},{"word":"der Nachweis","en":"proof; certificate of evidence","ru":"подтверждение, справка (документальное свидетельство)","vi":"bằng chứng","fa":"اثبات","examples":[{"de":"Für die Stelle brauchen Sie einen Nachweis Ihrer Deutschkenntnisse.","en":"For the job you need proof of your German skills.","ru":"Для работы нужна справка о знании немецкого языка.","vi":"Đối với vị trí này, bạn sẽ cần bằng chứng về kỹ năng tiếng Đức của mình.","fa":"برای این موقعیت به مدرکی مبنی بر مهارت زبان آلمانی خود نیاز دارید."},{"de":"Bitte bringen Sie einen Nachweis über Ihr Einkommen mit.","en":"Please bring proof of your income with you.","ru":"Возьмите, пожалуйста, справку о доходах.","vi":"Vui lòng mang theo bằng chứng về thu nhập của bạn.","fa":"لطفا مدرک درآمد خود را همراه داشته باشید."},{"de":"Ohne schriftlichen Nachweis wird die Versicherung nicht zahlen.","en":"Without written proof, the insurance will not pay.","ru":"Без письменного подтверждения страховая компания не заплатит.","vi":"Bảo hiểm sẽ không thanh toán nếu không có bằng chứng bằng văn bản.","fa":"بیمه بدون مدرک کتبی پرداخت نمی کند."}]},{"word":"nachweisen","en":"to prove, to provide evidence of","ru":"доказывать, подтверждать (документально)","vi":"chứng minh","fa":"ثابت کند","examples":[{"de":"Sie müssen Ihre Sprachkenntnisse nachweisen.","en":"You have to provide proof of your language skills.","ru":"Нужно подтвердить свои знания языка.","vi":"Bạn phải chứng minh khả năng ngôn ngữ của mình.","fa":"شما باید مهارت زبان خود را ثابت کنید."},{"de":"Man konnte ihm den Fehler nicht nachweisen.","en":"They couldn't prove the mistake against him.","ru":"Ошибку не смогли ему доказать.","vi":"Lỗi không thể được chứng minh.","fa":"خطا ثابت نشد."},{"de":"Bitte weisen Sie Ihr Einkommen mit einem Beleg nach.","en":"Please prove your income with a document.","ru":"Пожалуйста, подтвердите свой доход документом.","vi":"Vui lòng cung cấp bằng chứng về thu nhập của bạn cùng với biên nhận.","fa":"لطفا مدرک درآمد خود را همراه با رسید ارائه دهید."}]},{"word":"der Nachwuchs","en":"offspring; young talent (new generation)","ru":"потомство; молодое поколение, молодые кадры","vi":"con cháu","fa":"فرزندان","examples":[{"de":"Die Firma sucht dringend qualifizierten Nachwuchs.","en":"The company urgently needs qualified young talent.","ru":"Компании срочно нужны квалифицированные молодые кадры.","vi":"Công ty đang khẩn trương tìm kiếm những người trẻ có năng lực.","fa":"این شرکت به شدت به دنبال جوانان واجد شرایط می باشد."},{"de":"Das Löwenpaar im Zoo hat Nachwuchs bekommen.","en":"The pair of lions at the zoo has had offspring.","ru":"У пары львов в зоопарке появилось потомство.","vi":"Cặp sư tử trong vườn thú đã sinh con.","fa":"جفت شیرهای باغ وحش صاحب فرزند شده اند."}]},{"word":"der Nacken","en":"nape, back of the neck","ru":"затылок, задняя часть шеи","vi":"cái cổ","fa":"گردن","examples":[{"de":"Lass den Nacken lang und die Schultern locker.","en":"Keep your neck long and your shoulders relaxed.","ru":"Держи шею вытянутой, а плечи расслабленными.","vi":"Để cổ dài và vai thư giãn.","fa":"گردن خود را بلند و شانه های خود را رها کنید."},{"de":"Nach dem Computer ist mein Nacken oft verspannt.","en":"After the computer my neck is often tense.","ru":"После компьютера у меня часто зажата шея.","vi":"Cổ tôi thường bị căng sau khi sử dụng máy tính.","fa":"گردن من اغلب بعد از استفاده از کامپیوتر متشنج است."},{"de":"Diese Übung entspannt den Nacken.","en":"This exercise relaxes the neck.","ru":"Это упражнение расслабляет шею.","vi":"Bài tập này giúp thư giãn cổ.","fa":"این تمرین گردن را شل می کند."}]},{"word":"die Nadel","en":"needle","ru":"игла, иголка","vi":"cái kim","fa":"سوزن","examples":[{"de":"Sie näht den Knopf mit Nadel und Faden an.","en":"She sews the button on with needle and thread.","ru":"Она пришивает пуговицу иголкой с ниткой.","vi":"Cô ấy khâu chiếc cúc lại bằng kim và chỉ.","fa":"او دکمه را با نخ و سوزن می دوزد."},{"de":"Der Arzt benutzt eine sterile Nadel für die Impfung.","en":"The doctor uses a sterile needle for the vaccination.","ru":"Врач использует стерильную иглу для прививки.","vi":"Bác sĩ sử dụng kim tiêm vô trùng để tiêm chủng.","fa":"پزشک از یک سوزن استریل برای واکسیناسیون استفاده می کند."}]},{"word":"der Nagel","en":"nail","ru":"гвоздь; ноготь","vi":"cái đinh","fa":"ناخن","examples":[{"de":"Er schlägt einen Nagel in die Wand, um das Bild aufzuhängen.","en":"He hammers a nail into the wall to hang the picture.","ru":"Он забивает гвоздь в стену, чтобы повесить картину.","vi":"Anh ta đóng một chiếc đinh vào tường để treo bức tranh.","fa":"او میخ را به دیوار می کوبد تا عکس را آویزان کند."},{"de":"Sie lackiert sich jeden Monat die Nägel.","en":"She paints her nails every month.","ru":"Она красит ногти каждый месяц.","vi":"Cô ấy sơn móng tay mỗi tháng.","fa":"او هر ماه ناخن هایش را رنگ می کند."}]},{"word":"nah(e)","en":"near, close","ru":"близкий, недалёкий","vi":"đóng","fa":"بستن","examples":[{"de":"Die Schule liegt ganz nah bei unserem Haus.","en":"The school is very close to our house.","ru":"Школа находится совсем рядом с нашим домом.","vi":"Trường học rất gần nhà của chúng tôi.","fa":"مدرسه به خانه ما خیلی نزدیک است."},{"de":"Wir haben eine nahe Beziehung zu unseren Nachbarn.","en":"We have a close relationship with our neighbors.","ru":"У нас близкие отношения с нашими соседями.","vi":"Chúng tôi có mối quan hệ chặt chẽ với hàng xóm của chúng tôi.","fa":"ما با همسایگان خود رابطه نزدیک داریم."}]},{"word":"nähen","en":"to sew","ru":"шить","vi":"khâu","fa":"دوختن","examples":[{"de":"Meine Großmutter näht mir ein neues Kleid.","en":"My grandmother is sewing me a new dress.","ru":"Моя бабушка шьёт мне новое платье.","vi":"Bà tôi đang may cho tôi một chiếc váy mới.","fa":"مادربزرگم در حال دوختن لباس جدید برای من است."},{"de":"Er hat gelernt, seine Hosen selbst zu nähen.","en":"He learned to sew his own trousers.","ru":"Он научился сам шить себе брюки.","vi":"Anh ấy đã học cách tự may quần cho mình.","fa":"دوخت شلوارش را خودش یاد گرفت."}]},{"word":"nähern","en":"to approach, to draw near (reflexive: sich nähern)","ru":"приближаться (возвр.: sich nähern)","vi":"cách tiếp cận","fa":"رویکرد","examples":[{"de":"Das Schiff näherte sich langsam dem Hafen.","en":"The ship slowly approached the harbour.","ru":"Корабль медленно приближался к гавани.","vi":"Con tàu từ từ tiến vào bến cảng.","fa":"کشتی به آرامی به بندر نزدیک شد."},{"de":"Der Sommer nähert sich seinem Ende.","en":"The summer is drawing to a close.","ru":"Лето подходит к концу.","vi":"Mùa hè sắp kết thúc.","fa":"تابستان به پایان می رسد."},{"de":"Vorsichtig näherte sie sich dem Pferd.","en":"Cautiously she approached the horse.","ru":"Осторожно она подошла к лошади.","vi":"Cô cẩn thận tiến lại gần con ngựa.","fa":"او با احتیاط به اسب نزدیک شد."}]},{"word":"die Nähmaschine","en":"sewing machine","ru":"швейная машинка","vi":"máy may","fa":"چرخ خیاطی","examples":[{"de":"Meine Oma näht ihre Kleider mit einer alten Nähmaschine.","en":"My grandma sews her dresses with an old sewing machine.","ru":"Моя бабушка шьёт платья на старой швейной машинке.","vi":"Bà tôi may quần áo bằng chiếc máy khâu cũ.","fa":"مادربزرگم لباس هایش را با چرخ خیاطی قدیمی می دوزد."},{"de":"Die neue Nähmaschine ist viel leiser als die alte.","en":"The new sewing machine is much quieter than the old one.","ru":"Новая швейная машинка гораздо тише старой.","vi":"Máy may mới êm hơn nhiều so với máy cũ.","fa":"چرخ خیاطی جدید بسیار کم صداتر از چرخ خیاطی قدیمی است."},{"de":"Kannst du mir zeigen, wie diese Nähmaschine funktioniert?","en":"Can you show me how this sewing machine works?","ru":"Можешь показать мне, как работает эта швейная машинка?","vi":"Bạn có thể chỉ cho tôi cách máy may này hoạt động được không?","fa":"آیا می توانید به من نشان دهید که این چرخ خیاطی چگونه کار می کند؟"}]},{"word":"der Nährstoff","en":"nutrient","ru":"питательное вещество","vi":"chất dinh dưỡng","fa":"ماده مغذی","examples":[{"de":"Obst und Gemüse enthalten viele wichtige Nährstoffe.","en":"Fruit and vegetables contain many important nutrients.","ru":"Во фруктах и овощах много важных питательных веществ.","vi":"Trái cây và rau quả chứa nhiều chất dinh dưỡng quan trọng.","fa":"میوه ها و سبزیجات حاوی بسیاری از مواد مغذی مهم هستند."},{"de":"Der Körper braucht verschiedene Nährstoffe, um gesund zu bleiben.","en":"The body needs various nutrients to stay healthy.","ru":"Организму нужны разные питательные вещества, чтобы оставаться здоровым.","vi":"Cơ thể cần nhiều chất dinh dưỡng khác nhau để luôn khỏe mạnh.","fa":"بدن برای سالم ماندن به مواد مغذی مختلفی نیاز دارد."},{"de":"Beim Kochen gehen manche Nährstoffe verloren.","en":"During cooking, some nutrients are lost.","ru":"При варке часть питательных веществ теряется.","vi":"Một số chất dinh dưỡng bị mất đi khi nấu nướng.","fa":"برخی از مواد مغذی هنگام پخت و پز از بین می روند."}]},{"word":"die Nahrung","en":"food, nourishment","ru":"пища, питание","vi":"thức ăn","fa":"غذا","examples":[{"de":"Der Körper braucht abwechslungsreiche Nahrung.","en":"The body needs varied food.","ru":"Телу нужна разнообразная пища.","vi":"Cơ thể cần thực phẩm đa dạng.","fa":"بدن به غذای متنوع نیاز دارد."},{"de":"Pflanzliche Nahrung ist oft leichter verdaulich.","en":"Plant-based food is often easier to digest.","ru":"Растительная пища часто легче переваривается.","vi":"Thực phẩm có nguồn gốc thực vật thường dễ tiêu hóa hơn.","fa":"غذاهای گیاهی اغلب راحت تر هضم می شوند."},{"de":"Ohne ausreichend Nahrung wird man schnell schwach.","en":"Without enough food you quickly become weak.","ru":"Без достаточного питания быстро слабеешь.","vi":"Không có đủ thức ăn bạn sẽ nhanh chóng trở nên yếu đuối.","fa":"بدون غذای کافی به سرعت ضعیف می شوید."}]},{"word":"das Nahrungsmittel","en":"food; foodstuff","ru":"продукт питания","vi":"thức ăn","fa":"غذا","examples":[{"de":"Obst und Gemüse sind wichtige Nahrungsmittel.","en":"Fruit and vegetables are important foods.","ru":"Фрукты и овощи — важные продукты питания.","vi":"Trái cây và rau quả là những thực phẩm quan trọng.","fa":"میوه ها و سبزیجات از مواد غذایی مهم هستند."},{"de":"Im Supermarkt gibt es viele verschiedene Nahrungsmittel.","en":"There are many different foods in the supermarket.","ru":"В супермаркете есть много разных продуктов питания.","vi":"Có rất nhiều loại thực phẩm khác nhau trong siêu thị.","fa":"در سوپرمارکت غذاهای مختلفی وجود دارد."}]},{"word":"der Name","en":"name","ru":"имя; название","vi":"cái tên","fa":"نام","examples":[{"de":"Wie ist dein Name?","en":"What is your name?","ru":"Как тебя зовут?","vi":"Tên bạn là gì?","fa":"اسمت چیه؟"},{"de":"Sie hat ihren Namen geändert.","en":"She changed her name.","ru":"Она поменяла своё имя.","vi":"Cô ấy đã đổi tên.","fa":"اسمشو عوض کرد"}]},{"word":"nämlich","en":"namely; because (explanatory)","ru":"а именно; дело в том, что","vi":"cụ thể là","fa":"یعنی","examples":[{"de":"Ich kann heute nicht kommen, ich bin nämlich krank.","en":"I can't come today, because I'm sick.","ru":"Я не могу прийти сегодня, дело в том, что я болен.","vi":"Hôm nay tôi không thể đến vì tôi bị ốm.","fa":"امروز نمیتونم بیام چون مریضم"},{"de":"Wir brauchen zwei Dinge, nämlich Zeit und Geld.","en":"We need two things, namely time and money.","ru":"Нам нужны две вещи, а именно время и деньги.","vi":"Chúng ta cần hai thứ, đó là thời gian và tiền bạc.","fa":"ما به دو چیز نیاز داریم، یعنی زمان و پول."}]},{"word":"die Nase","en":"nose","ru":"нос","vi":"cái mũi","fa":"بینی","examples":[{"de":"Meine Nase ist verstopft.","en":"My nose is blocked.","ru":"У меня заложен нос.","vi":"Mũi tôi nghẹt quá.","fa":"بینی من گرفتگی دارد."},{"de":"Das Kind putzt sich die Nase.","en":"The child blows his nose.","ru":"Ребёнок сморкается.","vi":"Đứa trẻ xì mũi.","fa":"بچه دماغش را می زند."}]},{"word":"die Nase voll haben","en":"to be fed up (with something)","ru":"быть сытым по горло (чем-то)","vi":"chán ngấy","fa":"سیر شدن","examples":[{"de":"Ich habe die Nase voll von diesem Regen.","en":"I'm fed up with this rain.","ru":"Я сыт по горло этим дождём.","vi":"Tôi chán cơn mưa này rồi.","fa":"حالم از این بارون بهم میخوره"}]},{"word":"nass","en":"wet","ru":"мокрый","vi":"ướt","fa":"مرطوب","examples":[{"de":"Meine Schuhe sind vom Regen ganz nass.","en":"My shoes are completely wet from the rain.","ru":"Мои туфли совсем мокрые от дождя.","vi":"Giày của tôi ướt hoàn toàn vì mưa.","fa":"کفش هایم از باران کاملا خیس شده است."},{"de":"Zieh die nasse Jacke aus!","en":"Take off the wet jacket!","ru":"Сними мокрую куртку!","vi":"Hãy cởi áo khoác ướt của bạn ra!","fa":"ژاکت خیس خود را در بیاور!"}]},{"word":"national","en":"national","ru":"национальный","vi":"toàn quốc","fa":"در سطح ملی","examples":[{"de":"Morgen ist ein nationaler Feiertag.","en":"Tomorrow is a national holiday.","ru":"Завтра национальный праздник.","vi":"Ngày mai là ngày lễ quốc gia.","fa":"فردا تعطیلات ملی است."},{"de":"Die Nachrichten berichten über nationale Themen.","en":"The news reports on national topics.","ru":"Новости сообщают о национальных темах.","vi":"Các tin tức đưa tin về các vấn đề quốc gia.","fa":"اخبار مربوط به مسائل ملی است."}]},{"word":"die Natur","en":"nature","ru":"природа","vi":"bản chất","fa":"طبیعت","examples":[{"de":"Wir machen gern Ausflüge in die Natur.","en":"We like to go on trips into nature.","ru":"Мы любим ездить на природу.","vi":"Chúng tôi thích đi du lịch vào thiên nhiên.","fa":"ما دوست داریم به طبیعت سفر کنیم."},{"de":"Die Natur muss geschützt werden.","en":"Nature must be protected.","ru":"Природу нужно защищать.","vi":"Thiên nhiên phải được bảo vệ.","fa":"طبیعت باید محافظت شود."}]},{"word":"das Naturgesetz","en":"law of nature","ru":"закон природы","vi":"quy luật tự nhiên","fa":"قانون طبیعی","examples":[{"de":"Die Schwerkraft ist ein grundlegendes Naturgesetz.","en":"Gravity is a fundamental law of nature.","ru":"Сила тяжести — фундаментальный закон природы.","vi":"Trọng lực là một định luật cơ bản của tự nhiên.","fa":"جاذبه یک قانون اساسی طبیعت است."},{"de":"Kein Mensch kann ein Naturgesetz außer Kraft setzen.","en":"No human can override a law of nature.","ru":"Ни один человек не может отменить закон природы.","vi":"Không con người nào có thể vượt qua được quy luật tự nhiên.","fa":"هیچ انسانی نمی تواند قانون طبیعت را زیر پا بگذارد."},{"de":"Forscher versuchen, neue Naturgesetze zu entdecken.","en":"Researchers try to discover new laws of nature.","ru":"Учёные пытаются открыть новые законы природы.","vi":"Các nhà nghiên cứu đang cố gắng khám phá những quy luật mới của tự nhiên.","fa":"محققان در تلاش برای کشف قوانین جدید طبیعت هستند."}]},{"word":"die Naturkatastrophe","en":"natural disaster","ru":"стихийное бедствие","vi":"thảm họa thiên nhiên","fa":"بلای طبیعی","examples":[{"de":"Durch den Klimawandel nehmen Naturkatastrophen weltweit zu.","en":"Because of climate change, natural disasters are increasing worldwide.","ru":"Из-за изменения климата стихийные бедствия во всём мире учащаются.","vi":"Thiên tai đang gia tăng trên toàn thế giới do biến đổi khí hậu.","fa":"بلایای طبیعی به دلیل تغییرات آب و هوایی در سراسر جهان در حال افزایش است."},{"de":"Nach der Naturkatastrophe brauchten Tausende Menschen Hilfe.","en":"After the natural disaster thousands of people needed help.","ru":"После стихийного бедствия тысячам людей понадобилась помощь.","vi":"Sau thảm họa thiên nhiên, hàng nghìn người cần được giúp đỡ.","fa":"پس از فاجعه طبیعی، هزاران نفر به کمک نیاز داشتند."},{"de":"Überschwemmungen und Stürme sind häufige Naturkatastrophen.","en":"Floods and storms are common natural disasters.","ru":"Наводнения и штормы — частые стихийные бедствия.","vi":"Lũ lụt, bão là loại thiên tai thường gặp.","fa":"سیل و طوفان از بلایای طبیعی رایج هستند."}]},{"word":"natürlich","en":"naturally; of course","ru":"конечно; естественно","vi":"tất nhiên","fa":"البته","examples":[{"de":"Natürlich helfe ich dir.","en":"Of course I'll help you.","ru":"Конечно, я тебе помогу.","vi":"Tất nhiên là tôi sẽ giúp bạn.","fa":"البته من به شما کمک خواهم کرد."},{"de":"Das ist ein ganz natürliches Verhalten.","en":"That is a completely natural behavior.","ru":"Это совершенно естественное поведение.","vi":"Đây là hành vi hoàn toàn tự nhiên.","fa":"این رفتار کاملا طبیعی است."}]},{"word":"der Naturschutz","en":"nature conservation","ru":"охрана природы","vi":"bảo tồn thiên nhiên","fa":"حفاظت از طبیعت","examples":[{"de":"Der Naturschutz ist ihm sehr wichtig.","en":"Nature conservation is very important to him.","ru":"Охрана природы для него очень важна.","vi":"Bảo tồn thiên nhiên là rất quan trọng đối với anh ấy.","fa":"حفظ طبیعت برای او بسیار مهم است."},{"de":"In diesem Gebiet gilt strenger Naturschutz.","en":"Strict nature conservation applies in this area.","ru":"На этой территории действует строгая охрана природы.","vi":"Bảo tồn thiên nhiên nghiêm ngặt được áp dụng trong lĩnh vực này.","fa":"حفاظت از طبیعت سختگیرانه در این منطقه اعمال می شود."},{"de":"Viele Freiwillige arbeiten im Naturschutz mit.","en":"Many volunteers help out with nature conservation.","ru":"Многие волонтёры участвуют в охране природы.","vi":"Nhiều tình nguyện viên làm việc trong lĩnh vực bảo tồn thiên nhiên.","fa":"بسیاری از داوطلبان در حفاظت از طبیعت کار می کنند."}]},{"word":"der Nebel","en":"fog","ru":"туман","vi":"sương mù","fa":"مه","examples":[{"de":"Heute Morgen war dichter Nebel.","en":"There was thick fog this morning.","ru":"Сегодня утром был густой туман.","vi":"Sáng nay có sương mù dày đặc.","fa":"امروز صبح مه غلیظی بود."},{"de":"Wegen des Nebels sieht man kaum etwas.","en":"Because of the fog you can hardly see anything.","ru":"Из-за тумана почти ничего не видно.","vi":"Vì sương mù nên bạn khó có thể nhìn thấy gì.","fa":"به دلیل مه به سختی می توانید چیزی ببینید."}]},{"word":"neben","en":"next to; beside","ru":"рядом с; возле","vi":"bên cạnh","fa":"در کنار","examples":[{"de":"Der Stuhl steht neben dem Tisch.","en":"The chair is next to the table.","ru":"Стул стоит рядом со столом.","vi":"Cái ghế ở cạnh cái bàn.","fa":"صندلی کنار میز است."},{"de":"Neben der Schule gibt es einen Park.","en":"Next to the school there is a park.","ru":"Рядом со школой есть парк.","vi":"Có công viên cạnh trường học.","fa":"پارکی در کنار مدرسه وجود دارد."}]},{"word":"nebenbei","en":"on the side; incidentally","ru":"между делом; попутно","vi":"bên cạnh","fa":"در کنار","examples":[{"de":"Er studiert und arbeitet nebenbei in einem Café.","en":"He studies and works on the side in a café.","ru":"Он учится и подрабатывает попутно в кафе.","vi":"Anh ấy học và làm việc bán thời gian ở một quán cà phê.","fa":"او درس می خواند و به صورت پاره وقت در یک کافه کار می کند."},{"de":"Nebenbei bemerkt, das Essen war ausgezeichnet.","en":"Incidentally, the food was excellent.","ru":"Кстати говоря, еда была отличной.","vi":"Bên cạnh đó, thức ăn rất tuyệt vời.","fa":"از یک طرف، غذا عالی بود."}]},{"word":"der Neffe","en":"nephew","ru":"племянник","vi":"cháu trai","fa":"برادرزاده","examples":[{"de":"Mein Neffe kommt uns am Wochenende besuchen.","en":"My nephew is coming to visit us this weekend.","ru":"Мой племянник приедет к нам в гости на выходных.","vi":"Cháu trai của tôi sẽ đến thăm chúng tôi vào cuối tuần này.","fa":"برادرزاده ام این آخر هفته به دیدن ما می آید."},{"de":"Ich habe meinem Neffen ein Geschenk gekauft.","en":"I bought my nephew a gift.","ru":"Я купил племяннику подарок.","vi":"Tôi đã mua cho cháu trai tôi một món quà.","fa":"برای برادرزاده ام هدیه خریدم."}]},{"word":"negativ","en":"negative","ru":"отрицательный; негативный","vi":"tiêu cực","fa":"منفی","examples":[{"de":"Der Test war negativ.","en":"The test was negative.","ru":"Тест был отрицательным.","vi":"Der Test chiến tranh tiêu cực.","fa":"آزمایش منفی بود."},{"de":"Bitte denk nicht so negativ über die Zukunft.","en":"Please don't think so negatively about the future.","ru":"Пожалуйста, не думай так негативно о будущем.","vi":"Xin đừng suy nghĩ tiêu cực về tương lai.","fa":"لطفا در مورد آینده اینقدر منفی فکر نکنید."}]},{"word":"nehmen","en":"to take","ru":"брать; взять","vi":"lấy","fa":"گرفتن","examples":[{"de":"Nimm bitte deine Tasche mit.","en":"Please take your bag with you.","ru":"Пожалуйста, возьми свою сумку с собой.","vi":"Vui lòng mang theo túi của bạn.","fa":"لطفا کیف خود را با خود ببرید."},{"de":"Ich nehme den Zug um acht Uhr.","en":"I'll take the train at eight o'clock.","ru":"Я поеду на поезде в восемь часов.","vi":"Tôi bắt chuyến tàu lúc tám giờ.","fa":"سوار قطار ساعت هشت می شوم."}]},{"word":"nein","en":"no","ru":"нет","vi":"không","fa":"نه","examples":[{"de":"Nein, ich habe keine Zeit heute.","en":"No, I don't have time today.","ru":"Нет, у меня сегодня нет времени.","vi":"Không, hôm nay tôi không có thời gian.","fa":"نه امروز وقت ندارم"},{"de":"Sie hat auf meine Frage nein gesagt.","en":"She said no to my question.","ru":"Она сказала нет на мой вопрос.","vi":"Cô ấy nói không với câu hỏi của tôi.","fa":"او به سوال من نه گفت."}]},{"word":"der Nektar","en":"nectar","ru":"нектар","vi":"mật hoa","fa":"شهد","examples":[{"de":"Im Glas funkelte ein süßer Nektar aus reifen Früchten.","en":"A sweet nectar of ripe fruit sparkled in the glass.","ru":"В бокале искрился сладкий нектар из спелых фруктов.","vi":"Một thứ mật hoa ngọt ngào của trái chín lấp lánh trong ly.","fa":"شهد شیرینی از میوه رسیده در لیوان می درخشید."},{"de":"Die Bienen sammeln den Nektar aus den Blüten.","en":"The bees gather the nectar from the flowers.","ru":"Пчёлы собирают нектар с цветов.","vi":"Những con ong thu thập mật hoa từ những bông hoa.","fa":"زنبورها شهد گل ها را جمع آوری می کنند."},{"de":"Aus dem Nektar der Pflanzen entsteht später Honig.","en":"Honey is later produced from the nectar of the plants.","ru":"Из нектара растений позже образуется мёд.","vi":"Mật ong sau đó được làm từ mật hoa của thực vật.","fa":"عسل بعداً از شهد گیاهان تهیه می شود."}]},{"word":"nennen","en":"to name; to call","ru":"называть","vi":"gọi","fa":"تماس بگیرید","examples":[{"de":"Wie nennt man dieses Gerät auf Deutsch?","en":"What is this device called in German?","ru":"Как называется это устройство по-немецки?","vi":"Bạn gọi thiết bị này trong tiếng Đức là gì?","fa":"به آلمانی به این دستگاه چه می گویید؟"},{"de":"Man kann mich einfach Tom nennen.","en":"You can just call me Tom.","ru":"Можешь просто называть меня Том.","vi":"Man kann mich einfach Tom nennen.","fa":"فقط میتونی منو تام صدا کنی"}]},{"word":"der Nenner","en":"denominator","ru":"знаменатель","vi":"mẫu số","fa":"مخرج","examples":[{"de":"Der Nenner steht unter dem Bruchstrich.","en":"The denominator is below the fraction line.","ru":"Знаменатель стоит под дробной чертой.","vi":"Mẫu số nằm dưới dòng phân số.","fa":"مخرج زیر خط کسری است."},{"de":"Um Brüche zu addieren, braucht man einen gemeinsamen Nenner.","en":"To add fractions you need a common denominator.","ru":"Чтобы складывать дроби, нужен общий знаменатель.","vi":"Để cộng các phân số cần có mẫu số chung.","fa":"برای اضافه کردن کسرها به یک مخرج مشترک نیاز دارید."},{"de":"Im Bruch drei Viertel ist vier der Nenner.","en":"In the fraction three quarters, four is the denominator.","ru":"В дроби три четверти четыре — это знаменатель.","vi":"Trong phân số ba phần tư, bốn là mẫu số.","fa":"در کسر سه چهارم، چهار مخرج است."}]},{"word":"der Nerv","en":"nerve","ru":"нерв","vi":"dây thần kinh","fa":"عصب","examples":[{"de":"Die laute Musik geht mir auf die Nerven.","en":"The loud music gets on my nerves.","ru":"Громкая музыка действует мне на нервы.","vi":"Âm nhạc ồn ào làm tôi khó chịu.","fa":"صدای بلند موسیقی اعصابم را به هم می زند."},{"de":"Der Arzt hat einen Nerv im Rücken untersucht.","en":"The doctor examined a nerve in the back.","ru":"Врач осмотрел нерв в спине.","vi":"Bác sĩ kiểm tra dây thần kinh ở lưng.","fa":"دکتر عصب پشت را معاینه کرد."}]},{"word":"nerven","en":"to get on someone's nerves, to annoy","ru":"действовать на нервы, раздражать","vi":"dây thần kinh","fa":"اعصاب","examples":[{"de":"Dein ständiges Reden nervt mich wirklich.","en":"Your constant talking really gets on my nerves.","ru":"Твоя постоянная болтовня действительно действует мне на нервы.","vi":"Việc bạn nói chuyện liên tục thực sự làm tôi khó chịu.","fa":"صحبت های مداوم شما واقعاً من را آزار می دهد."},{"de":"Hör auf, mich zu nerven, ich habe keine Zeit.","en":"Stop annoying me, I haven't got any time.","ru":"Перестань меня доставать, у меня нет времени.","vi":"Đừng làm phiền tôi nữa, tôi không có thời gian.","fa":"دیگه اذیتم نکن وقت ندارم"},{"de":"Die laute Musik der Nachbarn nervt jeden im Haus.","en":"The neighbours' loud music annoys everyone in the building.","ru":"Громкая музыка соседей раздражает весь дом.","vi":"Tiếng nhạc ồn ào của hàng xóm làm phiền mọi người trong nhà.","fa":"صدای بلند همسایه ها همه را در خانه آزار می دهد."}]},{"word":"nervig","en":"annoying","ru":"раздражающий, надоедливый","vi":"khó chịu","fa":"آزار دهنده","examples":[{"de":"Der Lärm auf der Baustelle ist wirklich nervig.","en":"The noise from the building site is really annoying.","ru":"Шум со стройки действительно раздражает.","vi":"Tiếng ồn ở công trường thực sự khó chịu.","fa":"سر و صدا در محل ساخت و ساز واقعا آزار دهنده است."},{"de":"Es ist nervig, jeden Tag im Stau zu stehen.","en":"It's annoying to sit in a traffic jam every day.","ru":"Надоедает каждый день сидеть в пробке.","vi":"Thật khó chịu khi bị kẹt xe mỗi ngày.","fa":"گیر کردن هر روز در ترافیک آزاردهنده است."},{"de":"Mein Kollege stellt nervige Fragen.","en":"My colleague asks annoying questions.","ru":"Мой коллега задаёт надоедливые вопросы.","vi":"Đồng nghiệp của tôi hỏi những câu hỏi khó chịu.","fa":"همکارم سوالات آزاردهنده ای می پرسد."}]},{"word":"nervös","en":"nervous","ru":"нервный; взволнованный","vi":"lo lắng","fa":"عصبی","examples":[{"de":"Vor der Prüfung war ich sehr nervös.","en":"I was very nervous before the exam.","ru":"Перед экзаменом я очень нервничал.","vi":"Tôi đã rất lo lắng trước kỳ thi.","fa":"قبل از امتحان خیلی عصبی بودم."},{"de":"Werde nicht nervös, alles wird gut.","en":"Don't get nervous, everything will be fine.","ru":"Не нервничай, всё будет хорошо.","vi":"Đừng lo lắng, mọi thứ sẽ ổn thôi.","fa":"عصبی نشو همه چیز درست میشه"}]},{"word":"die Nervosität","en":"nervousness","ru":"нервозность, волнение","vi":"sự lo lắng","fa":"عصبی بودن","examples":[{"de":"Vor dem Vorstellungsgespräch konnte ich meine Nervosität kaum verbergen.","en":"Before the job interview I could hardly hide my nervousness.","ru":"Перед собеседованием я едва мог скрыть волнение.","vi":"Trước buổi phỏng vấn, tôi khó có thể giấu được sự lo lắng của mình.","fa":"قبل از مصاحبه به سختی می توانستم عصبی بودنم را پنهان کنم."},{"de":"Seine Nervosität war ihm deutlich anzusehen.","en":"His nervousness was clearly visible on him.","ru":"Его нервозность была хорошо заметна.","vi":"Có thể thấy rõ sự lo lắng của anh ấy.","fa":"اعصابش مشخص بود."},{"de":"Ein Tee half mir, die Nervosität zu beruhigen.","en":"A tea helped me to calm the nervousness.","ru":"Чай помог мне успокоить нервы.","vi":"Một tách trà đã giúp tôi xoa dịu nỗi lo lắng.","fa":"یک چای به آرام کردن اعصابم کمک کرد."}]},{"word":"nett","en":"nice; kind","ru":"милый; приятный","vi":"tốt đẹp","fa":"خوب","examples":[{"de":"Meine neuen Kollegen sind sehr nett.","en":"My new colleagues are very nice.","ru":"Мои новые коллеги очень милые.","vi":"My new colleagues are very nice.","fa":"همکاران جدید من خیلی خوب هستند."},{"de":"Das war nett von dir, danke!","en":"That was nice of you, thanks!","ru":"Это было мило с твоей стороны, спасибо!","vi":"Bạn thật tử tế, cảm ơn bạn!","fa":"از شما خوب بود، متشکرم!"}]},{"word":"das Netz","en":"net; network","ru":"сеть","vi":"mạng lưới","fa":"شبکه","examples":[{"de":"Der Fischer wirft sein Netz ins Wasser.","en":"The fisherman throws his net into the water.","ru":"Рыбак забрасывает сеть в воду.","vi":"Người đánh cá ném lưới xuống nước.","fa":"ماهیگیر تور خود را در آب می اندازد."},{"de":"Ich habe hier kein Netz auf dem Handy.","en":"I have no signal on my phone here.","ru":"У меня здесь нет сети на телефоне.","vi":"Điện thoại di động của tôi ở đây không có mạng.","fa":"من اینجا شبکه ای روی تلفن همراهم ندارم."}]},{"word":"das Netzwerk","en":"network","ru":"сеть (компьютерная/социальная)","vi":"mạng lưới","fa":"شبکه","examples":[{"de":"Unser Computer ist mit dem Netzwerk verbunden.","en":"Our computer is connected to the network.","ru":"Наш компьютер подключён к сети.","vi":"Máy tính của chúng tôi được kết nối với mạng.","fa":"کامپیوتر ما به شبکه متصل است."},{"de":"Sie hat ein großes berufliches Netzwerk.","en":"She has a large professional network.","ru":"У неё большая профессиональная сеть контактов.","vi":"Cô ấy có một mạng lưới chuyên nghiệp rộng lớn.","fa":"او یک شبکه حرفه ای بزرگ دارد."}]},{"word":"neu","en":"new","ru":"новый","vi":"mới","fa":"جدید","examples":[{"de":"Ich habe mir ein neues Fahrrad gekauft.","en":"I bought myself a new bike.","ru":"Я купил себе новый велосипед.","vi":"Tôi đã mua một chiếc xe đạp mới.","fa":"من یک دوچرخه جدید خریدم."},{"de":"Das ist mein neuer Kollege.","en":"This is my new colleague.","ru":"Это мой новый коллега.","vi":"Đây là đồng nghiệp mới của tôi.","fa":"این همکار جدید من است."}]},{"word":"die Neugier","en":"curiosity","ru":"любопытство","vi":"sự tò mò","fa":"کنجکاوی","examples":[{"de":"Aus reiner Neugier öffnete er die Tür.","en":"Out of pure curiosity he opened the door.","ru":"Из чистого любопытства он открыл дверь.","vi":"Vì tò mò, anh mở cửa.","fa":"از روی کنجکاوی محض در را باز کرد."},{"de":"Kinder haben eine natürliche Neugier auf die Welt.","en":"Children have a natural curiosity about the world.","ru":"У детей есть естественное любопытство к миру.","vi":"Trẻ em có sự tò mò tự nhiên về thế giới.","fa":"کودکان نسبت به دنیا کنجکاوی طبیعی دارند."}]},{"word":"neugierig","en":"curious","ru":"любопытный","vi":"tò mò","fa":"کنجکاو","examples":[{"de":"Die Kinder sind sehr neugierig auf die Antwort.","en":"The children are very curious about the answer.","ru":"Дети очень любопытны узнать ответ.","vi":"Các em rất tò mò về câu trả lời.","fa":"بچه ها در مورد پاسخ بسیار کنجکاو هستند."},{"de":"Sei nicht so neugierig, das ist privat!","en":"Don't be so nosy, that's private!","ru":"Не будь таким любопытным, это личное!","vi":"Đừng tọc mạch thế, đây là chuyện riêng tư!","fa":"اینقدر فضول نباش، این خصوصی است!"}]},{"word":"die Neuigkeit","en":"news; a piece of news","ru":"новость","vi":"tin tức","fa":"اخبار","examples":[{"de":"Ich habe eine tolle Neuigkeit für dich!","en":"I have great news for you!","ru":"У меня для тебя отличная новость!","vi":"Tôi có tin tuyệt vời cho bạn!","fa":"من یک خبر عالی برای شما دارم!"},{"de":"Hast du schon die neueste Neuigkeit gehört?","en":"Have you already heard the latest news?","ru":"Ты уже слышал последнюю новость?","vi":"Bạn đã nghe tin tức mới nhất chưa?","fa":"آیا تا به حال آخرین اخبار را شنیده اید؟"}]},{"word":"neulich","en":"recently; the other day","ru":"недавно; на днях","vi":"gần đây","fa":"اخیرا","examples":[{"de":"Neulich habe ich einen alten Freund getroffen.","en":"The other day I met an old friend.","ru":"Недавно я встретил старого друга.","vi":"Gần đây tôi đã gặp một người bạn cũ.","fa":"اخیراً با یک دوست قدیمی آشنا شدم."},{"de":"Neulich gab es einen interessanten Bericht im Fernsehen.","en":"Recently there was an interesting report on TV.","ru":"На днях по телевизору был интересный репортаж.","vi":"Gần đây có một bản tin thú vị trên truyền hình.","fa":"اخیرا گزارش جالبی در تلویزیون پخش شد."}]},{"word":"nicht","en":"not","ru":"не","vi":"không","fa":"نه","examples":[{"de":"Ich verstehe das nicht.","en":"I don't understand that.","ru":"Я этого не понимаю.","vi":"Tôi không hiểu điều đó.","fa":"من این را نمی فهمم."},{"de":"Er ist heute nicht zu Hause.","en":"He is not at home today.","ru":"Его сегодня нет дома.","vi":"Hôm nay anh ấy không có nhà.","fa":"امروز خونه نیست"}]},{"word":"die Nichte","en":"niece","ru":"племянница","vi":"cháu gái","fa":"خواهرزاده","examples":[{"de":"Meine Nichte wird nächste Woche zehn Jahre alt.","en":"My niece will turn ten next week.","ru":"Моей племяннице на следующей неделе исполнится десять лет.","vi":"Cháu gái tôi tròn mười tuổi vào tuần tới.","fa":"خواهرزاده من هفته آینده ده ساله می شود."},{"de":"Ich schreibe meiner Nichte oft Briefe.","en":"I often write letters to my niece.","ru":"Я часто пишу письма своей племяннице.","vi":"Tôi thường viết thư cho cháu gái của tôi.","fa":"من اغلب برای خواهرزاده ام نامه می نویسم."}]},{"word":"der Nichtraucher","en":"non-smoker","ru":"некурящий","vi":"người không hút thuốc","fa":"غیر سیگاری","examples":[{"de":"Er ist seit einem Jahr Nichtraucher.","en":"He has been a non-smoker for a year.","ru":"Он не курит уже год.","vi":"Anh ấy đã không hút thuốc được một năm.","fa":"او یک سال است که سیگار نمی کشد."},{"de":"Dieser Wagen ist nur für Nichtraucher.","en":"This carriage is only for non-smokers.","ru":"Этот вагон только для некурящих.","vi":"Chiếc xe này chỉ dành cho người không hút thuốc.","fa":"این خودرو فقط برای افراد غیر سیگاری است."}]},{"word":"die Nichtraucherin","en":"non-smoker (female)","ru":"некурящая (женщина)","vi":"người không hút thuốc","fa":"غیر سیگاری","examples":[{"de":"Meine Schwester ist überzeugte Nichtraucherin.","en":"My sister is a committed non-smoker.","ru":"Моя сестра — убеждённая некурящая.","vi":"Em gái tôi là một người không hút thuốc.","fa":"خواهر من یک غیر سیگاری متعهد است."},{"de":"Als Nichtraucherin meidet sie verrauchte Bars.","en":"As a non-smoker, she avoids smoky bars.","ru":"Как некурящая, она избегает прокуренных баров.","vi":"Là người không hút thuốc, cô tránh những quán bar đầy khói thuốc.","fa":"به عنوان یک غیر سیگاری، او از بارهای دودی اجتناب می کند."},{"de":"Die neue Kollegin ist auch Nichtraucherin.","en":"The new colleague is also a non-smoker.","ru":"Новая коллега тоже некурящая.","vi":"Đồng nghiệp mới cũng là người không hút thuốc.","fa":"همکار جدید هم سیگاری نیست."}]},{"word":"nichts","en":"nothing","ru":"ничего","vi":"không có gì","fa":"هیچ چیز","examples":[{"de":"Ich habe heute nichts gegessen.","en":"I haven't eaten anything today.","ru":"Я сегодня ничего не ел.","vi":"Hôm nay tôi chưa ăn gì cả.","fa":"امروز هیچی نخوردم"},{"de":"Das macht nichts, kein Problem.","en":"It doesn't matter, no problem.","ru":"Ничего страшного, нет проблем.","vi":"Điều đó không quan trọng, không có vấn đề gì.","fa":"این مهم نیست، مشکلی نیست."}]},{"word":"nie","en":"never","ru":"никогда","vi":"không bao giờ","fa":"هرگز","examples":[{"de":"Ich war noch nie in Japan.","en":"I have never been to Japan.","ru":"Я никогда не был в Японии.","vi":"Tôi chưa bao giờ đến Nhật Bản.","fa":"من هرگز به ژاپن نرفته ام."},{"de":"Er kommt nie pünktlich.","en":"He never comes on time.","ru":"Он никогда не приходит вовремя.","vi":"Anh ấy không bao giờ đến đúng giờ.","fa":"او هرگز به موقع نمی آید."}]},{"word":"die Niederlage","en":"defeat","ru":"поражение","vi":"sự thất bại","fa":"the defeat","examples":[{"de":"Die Niederlage im Krieg veränderte das ganze Land.","en":"The defeat in the war changed the whole country.","ru":"Поражение в войне изменило всю страну.","vi":"Thất bại trong chiến tranh đã thay đổi cả đất nước.","fa":"شکست در جنگ کل کشور را تغییر داد."},{"de":"Nach der Niederlage musste der König abdanken.","en":"After the defeat the king had to abdicate.","ru":"После поражения королю пришлось отречься от престола.","vi":"Sau thất bại, nhà vua phải thoái vị.","fa":"پس از شکست، پادشاه مجبور شد از سلطنت کناره گیری کند."},{"de":"Die schwere Niederlage führte zu einer Revolution.","en":"The heavy defeat led to a revolution.","ru":"Тяжёлое поражение привело к революции.","vi":"Sự thất bại nặng nề đã dẫn đến một cuộc cách mạng.","fa":"شکست سخت منجر به انقلاب شد."}]},{"word":"niedrig","en":"low","ru":"низкий","vi":"thấp","fa":"پایین","examples":[{"de":"Die Preise in diesem Geschäft sind sehr niedrig.","en":"The prices in this shop are very low.","ru":"Цены в этом магазине очень низкие.","vi":"Giá ở cửa hàng này rất thấp.","fa":"قیمت ها در این فروشگاه بسیار پایین است."},{"de":"Die Decke im Keller ist ziemlich niedrig.","en":"The ceiling in the basement is quite low.","ru":"Потолок в подвале довольно низкий.","vi":"Trần ở tầng hầm khá thấp.","fa":"سقف در زیرزمین بسیار کم است."}]},{"word":"niemand","en":"nobody; no one","ru":"никто","vi":"không ai","fa":"هیچ کس","examples":[{"de":"Niemand hat mir geholfen.","en":"Nobody helped me.","ru":"Никто мне не помог.","vi":"Không ai giúp tôi cả.","fa":"هیچکس به من کمک نکرد"},{"de":"Im Büro war heute niemand.","en":"There was nobody in the office today.","ru":"В офисе сегодня никого не было.","vi":"Hôm nay ở văn phòng không có ai cả.","fa":"امروز کسی در دفتر نبود."}]},{"word":"nirgends","en":"nowhere","ru":"нигде","vi":"hư không","fa":"هیچ جا","examples":[{"de":"Ich kann meinen Schlüssel nirgends finden.","en":"I can't find my key anywhere.","ru":"Я нигде не могу найти свой ключ.","vi":"Tôi không thể tìm thấy chìa khóa của mình ở đâu cả.","fa":"من هیچ جا کلیدم را پیدا نمی کنم."},{"de":"Sie fühlt sich nirgends so wohl wie zu Hause.","en":"She feels nowhere as comfortable as at home.","ru":"Ей нигде не так хорошо, как дома.","vi":"Cô ấy không cảm thấy thoải mái ở bất cứ đâu như ở nhà.","fa":"او در هیچ کجا به اندازه خانه احساس راحتی نمی کند."}]},{"word":"nirgendwo","en":"nowhere","ru":"нигде","vi":"hư không","fa":"هیچ جا","examples":[{"de":"Diesen Artikel gibt es nirgendwo zu kaufen.","en":"This item can be bought nowhere.","ru":"Этот товар нигде не купить.","vi":"Mặt hàng này không có sẵn để mua ở bất cứ đâu.","fa":"این کالا در هیچ کجا قابل خرید نیست."},{"de":"Wir konnten nirgendwo einen Parkplatz finden.","en":"We couldn't find a parking spot anywhere.","ru":"Мы нигде не смогли найти парковку.","vi":"Chúng tôi không thể tìm thấy chỗ đậu xe ở bất cứ đâu.","fa":"هیچ جا جای پارک پیدا نکردیم."}]},{"word":"noch","en":"still; yet","ru":"ещё","vi":"chưa","fa":"هنوز","examples":[{"de":"Ich bin noch nicht fertig.","en":"I'm not finished yet.","ru":"Я ещё не закончил.","vi":"Tôi vẫn chưa xong việc.","fa":"من هنوز تمام نشده ام."},{"de":"Möchtest du noch einen Kaffee?","en":"Would you like another coffee?","ru":"Хочешь ещё кофе?","vi":"Bạn có muốn một ly cà phê khác không?","fa":"آیا قهوه دیگری می خواهید؟"}]},{"word":"noch mal","en":"once more; again","ru":"ещё раз","vi":"một lần nữa","fa":"دوباره","examples":[{"de":"Kannst du das bitte noch mal erklären?","en":"Can you please explain that once more?","ru":"Можешь объяснить это ещё раз, пожалуйста?","vi":"Bạn có thể vui lòng giải thích điều đó một lần nữa?","fa":"میشه لطفا دوباره توضیح بدید؟"},{"de":"Wir sehen uns noch mal am Freitag.","en":"We'll see each other again on Friday.","ru":"Мы увидимся ещё раз в пятницу.","vi":"Chúng ta sẽ gặp lại nhau vào thứ Sáu.","fa":"جمعه دوباره همدیگر را می بینیم."}]},{"word":"nochmal","en":"again, once more","ru":"ещё раз, снова","vi":"một lần nữa","fa":"دوباره","examples":[{"de":"Sag mir nochmal deine Telefonnummer.","en":"Tell me your phone number again.","ru":"Скажи мне свой номер телефона ещё раз.","vi":"Hãy cho tôi biết số điện thoại của bạn một lần nữa.","fa":"دوباره شماره تلفنت را بگو"},{"de":"Wir treffen uns nochmal nächste Woche.","en":"We'll meet again next week.","ru":"Мы снова встретимся на следующей неделе.","vi":"Chúng ta sẽ gặp lại vào tuần tới.","fa":"هفته آینده دوباره همدیگر را ملاقات خواهیم کرد."},{"de":"Er hat die Frage nochmal gestellt.","en":"He asked the question again.","ru":"Он снова задал вопрос.","vi":"Anh lại hỏi câu hỏi đó.","fa":"دوباره سوال را پرسید."}]},{"word":"nochmals","en":"once again; once more","ru":"ещё раз; повторно","vi":"một lần nữa","fa":"دوباره","examples":[{"de":"Ich möchte mich nochmals bei Ihnen bedanken.","en":"I would like to thank you once again.","ru":"Я хотел бы ещё раз поблагодарить вас.","vi":"Tôi muốn cảm ơn bạn một lần nữa.","fa":"باز هم می خواهم از شما تشکر کنم."},{"de":"Bitte prüfen Sie das Formular nochmals.","en":"Please check the form once more.","ru":"Пожалуйста, проверьте форму ещё раз.","vi":"Vui lòng kiểm tra lại biểu mẫu.","fa":"لطفا دوباره فرم را بررسی کنید."}]},{"word":"die Nordsee","en":"the North Sea","ru":"Северное море","vi":"Biển Bắc","fa":"دریای شمال","examples":[{"de":"Im Sommer fahren wir oft an die Nordsee.","en":"In summer we often go to the North Sea.","ru":"Летом мы часто ездим на Северное море.","vi":"Vào mùa hè chúng tôi thường đi biển Bắc.","fa":"در تابستان اغلب به دریای شمال می رویم."},{"de":"An der Nordsee ist der Wind meistens kräftig.","en":"At the North Sea the wind is usually strong.","ru":"На Северном море обычно сильный ветер.","vi":"Gió thường mạnh ở Biển Bắc.","fa":"باد معمولاً در دریای شمال شدید است."},{"de":"Die Nordsee ist viel rauer als die Ostsee.","en":"The North Sea is much rougher than the Baltic Sea.","ru":"Северное море гораздо суровее Балтийского.","vi":"Biển Bắc gồ ghề hơn nhiều so với biển Baltic.","fa":"دریای شمال بسیار ناهموارتر از دریای بالتیک است."}]},{"word":"die Norm","en":"norm, standard (of social behaviour)","ru":"норма (социального поведения)","vi":"chuẩn mực","fa":"هنجار","examples":[{"de":"Jede Gesellschaft hat ihre eigenen Normen.","en":"Every society has its own norms.","ru":"У каждого общества свои нормы.","vi":"Mỗi xã hội đều có những chuẩn mực riêng.","fa":"هر جامعه ای هنجارهای خاص خود را دارد."},{"de":"Soziale Normen sagen uns, wie wir uns verhalten sollen.","en":"Social norms tell us how we should behave.","ru":"Социальные нормы говорят нам, как мы должны себя вести.","vi":"Các chuẩn mực xã hội cho chúng ta biết chúng ta nên cư xử như thế nào.","fa":"هنجارهای اجتماعی به ما می گویند که چگونه باید رفتار کنیم."},{"de":"Wer gegen die Norm verstößt, wird oft kritisiert.","en":"Anyone who breaks the norm is often criticised.","ru":"Того, кто нарушает норму, часто критикуют.","vi":"Những người vi phạm chuẩn mực thường bị chỉ trích.","fa":"کسانی که هنجارها را زیر پا می گذارند اغلب مورد انتقاد قرار می گیرند."}]},{"word":"normal","en":"normal","ru":"нормальный","vi":"bình thường","fa":"عادی","examples":[{"de":"Ist es normal, dass die Heizung so laut ist?","en":"Is it normal for the heating to be this loud?","ru":"Это нормально, что отопление такое шумное?","vi":"Máy sưởi kêu to như vậy có phải là bình thường không?","fa":"آیا صدای بخاری اینقدر طبیعی است؟"},{"de":"Heute war ein ganz normaler Arbeitstag.","en":"Today was a completely normal working day.","ru":"Сегодня был совершенно обычный рабочий день.","vi":"Hôm nay là một ngày làm việc bình thường.","fa":"امروز یک روز کاری عادی بود."}]},{"word":"normalerweise","en":"normally, usually","ru":"обычно, как правило","vi":"thường","fa":"معمولا","examples":[{"de":"Normalerweise stehe ich um sieben Uhr auf.","en":"I normally get up at seven o'clock.","ru":"Обычно я встаю в семь часов.","vi":"Tôi thường thức dậy lúc bảy giờ.","fa":"من معمولا ساعت هفت بیدار می شوم."},{"de":"Das Geschäft ist normalerweise bis acht geöffnet.","en":"The shop is usually open until eight.","ru":"Магазин, как правило, открыт до восьми.","vi":"Cửa hàng thường mở cửa đến tám giờ.","fa":"فروشگاه معمولا تا ساعت هشت باز است."},{"de":"Normalerweise nehme ich den Bus zur Arbeit.","en":"I usually take the bus to work.","ru":"Обычно я езжу на работу на автобусе.","vi":"Tôi thường đi xe buýt đi làm.","fa":"من معمولاً برای سرکار با اتوبوس می روم."}]},{"word":"die Not","en":"need; hardship; distress","ru":"нужда, беда, бедствие","vi":"sự cần thiết","fa":"نیاز","examples":[{"de":"In der Not muss man einander helfen.","en":"In times of hardship people must help one another.","ru":"В трудные времена люди должны помогать друг другу.","vi":"Lúc khó khăn phải giúp đỡ lẫn nhau.","fa":"در مواقع ضروری باید به یکدیگر کمک کنید."},{"de":"Viele Familien leiden große Not.","en":"Many families are suffering great hardship.","ru":"Многие семьи испытывают большую нужду.","vi":"Nhiều gia đình đang gặp khó khăn lớn.","fa":"بسیاری از خانواده ها از سختی های زیادی رنج می برند."},{"de":"Aus der Not heraus verkaufte er sein Auto.","en":"Out of necessity he sold his car.","ru":"От нужды он продал свою машину.","vi":"Vì cần thiết, anh ấy đã bán chiếc xe của mình.","fa":"از سر ناچاری ماشینش را فروخت."}]},{"word":"Not-","en":"emergency- (prefix)","ru":"аварийный-; экстренный- (приставка)","vi":"trường hợp khẩn cấp","fa":"اضطراری","examples":[{"de":"Im Notfall wählen Sie die Nummer 112.","en":"In an emergency, dial 112.","ru":"В экстренном случае звоните по номеру 112.","vi":"Trong trường hợp khẩn cấp, hãy quay số 112.","fa":"در مواقع اضطراری 112 را شماره گیری کنید."},{"de":"Der Notausgang befindet sich links neben der Tür.","en":"The emergency exit is on the left next to the door.","ru":"Аварийный выход находится слева от двери.","vi":"Lối thoát hiểm nằm ở bên trái cửa.","fa":"خروجی اضطراری در سمت چپ در است."}]},{"word":"die Notaufnahme","en":"accident and emergency department","ru":"приёмное отделение неотложной помощи (в больнице)","vi":"phòng cấp cứu","fa":"اورژانس","examples":[{"de":"Nach dem Unfall brachte man ihn sofort in die Notaufnahme.","en":"After the accident he was taken straight to A&E.","ru":"После аварии его сразу отвезли в приёмное отделение.","vi":"Sau vụ tai nạn, anh lập tức được đưa đi cấp cứu.","fa":"پس از تصادف بلافاصله به اورژانس منتقل شد."},{"de":"In der Notaufnahme mussten wir lange warten.","en":"In the accident and emergency department we had to wait a long time.","ru":"В приёмном отделении нам пришлось долго ждать.","vi":"Chúng tôi phải đợi rất lâu ở phòng cấp cứu.","fa":"مجبور شدیم مدت زیادی در اورژانس منتظر بمانیم."},{"de":"Die Notaufnahme ist die ganze Nacht geöffnet.","en":"The emergency department is open all night.","ru":"Приёмное отделение открыто всю ночь.","vi":"Phòng cấp cứu mở cửa suốt đêm.","fa":"اورژانس تمام شب باز است."}]},{"word":"der Notausgang","en":"emergency exit","ru":"аварийный выход, запасной выход","vi":"lối thoát hiểm","fa":"خروجی اضطراری","examples":[{"de":"Der Notausgang befindet sich am Ende des Flurs.","en":"The emergency exit is at the end of the corridor.","ru":"Аварийный выход находится в конце коридора.","vi":"Lối thoát hiểm nằm ở cuối hành lang.","fa":"خروجی اضطراری در انتهای راهرو است."},{"de":"Bitte halten Sie den Notausgang immer frei.","en":"Please always keep the emergency exit clear.","ru":"Всегда держите аварийный выход свободным.","vi":"Vui lòng giữ lối thoát hiểm luôn thông thoáng.","fa":"لطفا خروجی اضطراری را همیشه روشن نگه دارید."},{"de":"Im Kino zeigt ein grünes Schild den Notausgang an.","en":"In the cinema a green sign indicates the emergency exit.","ru":"В кинотеатре зелёная табличка указывает на аварийный выход.","vi":"Trong rạp chiếu phim, biển báo màu xanh lá cây biểu thị lối thoát hiểm.","fa":"در سینما یک علامت سبز نشان دهنده خروج اضطراری است."}]},{"word":"die Note","en":"grade; mark (school); (musical) note","ru":"оценка; нота","vi":"ghi chú","fa":"یادداشت","examples":[{"de":"Ich habe in Mathe eine gute Note bekommen.","en":"I got a good grade in math.","ru":"Я получил хорошую оценку по математике.","vi":"Tôi đạt điểm cao môn toán.","fa":"من در ریاضی نمره خوبی گرفتم."},{"de":"Er kann die Noten auf dem Klavier nicht lesen.","en":"He can't read the notes on the piano.","ru":"Он не умеет читать ноты на пианино.","vi":"Anh ấy không thể đọc nhạc trên đàn piano.","fa":"او نمی تواند موسیقی را روی پیانو بخواند."}]},{"word":"der Notfall","en":"emergency","ru":"чрезвычайная ситуация, экстренный случай","vi":"trường hợp khẩn cấp","fa":"اورژانس","examples":[{"de":"Im Notfall wählen Sie bitte die 112.","en":"In an emergency please dial 112.","ru":"В экстренном случае звоните, пожалуйста, по номеру 112.","vi":"Trong trường hợp khẩn cấp, vui lòng quay số 112.","fa":"در مواقع اضطراری لطفا 112 را شماره گیری کنید."},{"de":"Für den Notfall habe ich immer etwas Bargeld dabei.","en":"For emergencies I always carry some cash with me.","ru":"На случай непредвиденных ситуаций я всегда ношу с собой немного наличных.","vi":"Tôi luôn mang theo một ít tiền mặt trong trường hợp khẩn cấp.","fa":"در مواقع ضروری همیشه مقداری پول نقد همراه خود دارم."},{"de":"Das ist ein Notfall, wir müssen sofort handeln!","en":"This is an emergency, we must act immediately!","ru":"Это чрезвычайная ситуация, нужно действовать немедленно!","vi":"Đây là trường hợp khẩn cấp, chúng ta phải hành động ngay lập tức!","fa":"این یک اورژانس است، ما باید فورا اقدام کنیم!"}]},{"word":"notieren","en":"to note down; to write down","ru":"записывать","vi":"ghi chú lại","fa":"یادداشت کنید","examples":[{"de":"Ich notiere mir die wichtigsten Punkte.","en":"I note down the most important points.","ru":"Я записываю самые важные моменты.","vi":"Tôi ghi lại những điểm quan trọng nhất.","fa":"مهم ترین نکات را یادداشت می کنم."},{"de":"Können Sie sich bitte meine Telefonnummer notieren?","en":"Could you please write down my phone number?","ru":"Не могли бы вы записать мой номер телефона?","vi":"Bạn có thể vui lòng ghi lại số điện thoại của tôi được không?","fa":"میشه لطفا شماره تلفن منو یادداشت کنید"}]},{"word":"nötig","en":"necessary","ru":"необходимый; нужный","vi":"cần thiết","fa":"لازم است","examples":[{"de":"Es ist nicht nötig, dass du dich entschuldigst.","en":"It is not necessary for you to apologize.","ru":"Тебе не обязательно извиняться.","vi":"Bạn không cần phải xin lỗi đâu.","fa":"نیازی به عذرخواهی نیست"},{"de":"Wir haben alle nötigen Unterlagen dabei.","en":"We have all the necessary documents with us.","ru":"У нас с собой все необходимые документы.","vi":"Chúng tôi có tất cả các tài liệu cần thiết với chúng tôi.","fa":"ما تمام مدارک لازم را با خود داریم."}]},{"word":"die Notiz","en":"note (written)","ru":"заметка; записка","vi":"ghi chú","fa":"یادداشت","examples":[{"de":"Ich habe mir eine Notiz gemacht, damit ich es nicht vergesse.","en":"I made a note so I wouldn't forget it.","ru":"Я сделал заметку, чтобы не забыть.","vi":"Mình đã note lại để khỏi quên.","fa":"یادداشت کردم که فراموش نکنم"},{"de":"Auf dem Tisch liegt eine Notiz von meiner Mutter.","en":"There is a note from my mother on the table.","ru":"На столе лежит записка от моей мамы.","vi":"Có một tờ giấy của mẹ tôi trên bàn.","fa":"یادداشتی از مادرم روی میز است."}]},{"word":"der Notruf","en":"emergency call","ru":"экстренный вызов, вызов служб спасения","vi":"cuộc gọi khẩn cấp","fa":"تماس اضطراری","examples":[{"de":"Sie setzte sofort einen Notruf ab.","en":"She made an emergency call straight away.","ru":"Она сразу же сделала экстренный вызов.","vi":"Cô lập tức gọi điện khẩn cấp.","fa":"او بلافاصله یک تماس اضطراری برقرار کرد."},{"de":"Der Notruf der Polizei ist die 110.","en":"The police emergency number is 110.","ru":"Номер экстренного вызова полиции — 110.","vi":"Số khẩn cấp của cảnh sát là 110.","fa":"شماره اورژانس پلیس 110 است."},{"de":"Nach dem Notruf war der Krankenwagen schnell da.","en":"After the emergency call, the ambulance arrived quickly.","ru":"После экстренного вызова скорая приехала быстро.","vi":"Sau cuộc gọi khẩn cấp, xe cứu thương nhanh chóng có mặt.","fa":"پس از تماس اورژانس، آمبولانس به سرعت رسید."}]},{"word":"die Notsituation","en":"emergency situation","ru":"экстренная ситуация, чрезвычайное положение","vi":"tình huống khẩn cấp","fa":"وضعیت اضطراری","examples":[{"de":"In einer Notsituation sollte man Ruhe bewahren.","en":"In an emergency situation one should stay calm.","ru":"В экстренной ситуации следует сохранять спокойствие.","vi":"Trong tình huống khẩn cấp bạn nên giữ bình tĩnh.","fa":"در شرایط اضطراری باید آرامش خود را حفظ کنید."},{"de":"Das Rote Kreuz hilft Menschen in Notsituationen.","en":"The Red Cross helps people in emergency situations.","ru":"Красный Крест помогает людям в экстренных ситуациях.","vi":"Hội Chữ Thập Đỏ giúp đỡ người dân trong những tình huống khẩn cấp.","fa":"صلیب سرخ به مردم در شرایط اضطراری کمک می کند."},{"de":"Für jede Notsituation gibt es einen festen Plan.","en":"For every emergency situation there is a fixed plan.","ru":"На каждую экстренную ситуацию есть чёткий план.","vi":"Có kế hoạch cố định cho mọi tình huống khẩn cấp.","fa":"برای هر موقعیت اضطراری یک برنامه ثابت وجود دارد."}]},{"word":"notwendig","en":"necessary","ru":"необходимый","vi":"cần thiết","fa":"لازم است","examples":[{"de":"Ein Regenschirm ist heute notwendig.","en":"An umbrella is necessary today.","ru":"Сегодня необходим зонт.","vi":"Một chiếc ô là cần thiết ngày hôm nay.","fa":"امروز یک چتر ضروری است."},{"de":"Ist es wirklich notwendig, so früh aufzustehen?","en":"Is it really necessary to get up this early?","ru":"Действительно ли необходимо вставать так рано?","vi":"Có thực sự cần thiết phải dậy sớm như vậy không?","fa":"آیا واقعاً لازم است اینقدر زود بیدار شویم؟"}]},{"word":"die Nudel","en":"noodle; pasta","ru":"лапша; макароны","vi":"mì","fa":"رشته فرنگی","examples":[{"de":"Zum Abendessen gibt es Nudeln mit Tomatensoße.","en":"For dinner there are noodles with tomato sauce.","ru":"На ужин макароны с томатным соусом.","vi":"Bữa tối có mì ống sốt cà chua.","fa":"برای شام پاستا با سس گوجه فرنگی وجود دارد."},{"de":"Die Nudeln müssen zehn Minuten kochen.","en":"The pasta needs to cook for ten minutes.","ru":"Макароны нужно варить десять минут.","vi":"Mì ống cần nấu trong mười phút.","fa":"پاستا باید ده دقیقه بپزد."}]},{"word":"die Nummer","en":"number","ru":"номер","vi":"số","fa":"شماره","examples":[{"de":"Kannst du mir deine Nummer geben?","en":"Can you give me your number?","ru":"Можешь дать мне свой номер?","vi":"Bạn có thể cho tôi số của bạn được không?","fa":"میشه شماره ات رو بهم بدی"},{"de":"Ich wohne in der Straße Nummer zwölf.","en":"I live at number twelve on this street.","ru":"Я живу в доме номер двенадцать на этой улице.","vi":"Tôi sống trên đường số mười hai.","fa":"من در خیابان شماره دوازده زندگی می کنم."}]},{"word":"das Nummernschild","en":"number plate; licence plate","ru":"номерной знак, автомобильный номер","vi":"biển số xe","fa":"پلاک","examples":[{"de":"Ich konnte mir das Nummernschild des Autos nicht merken.","en":"I could not remember the car's number plate.","ru":"Я не смог вспомнить номерной знак машины.","vi":"Tôi không thể nhớ được biển số xe.","fa":"پلاک ماشین را یادم نمی آمد."},{"de":"Das Nummernschild zeigt, aus welcher Stadt das Auto kommt.","en":"The number plate shows which city the car comes from.","ru":"По номерному знаку видно, из какого города машина.","vi":"Biển số xe cho biết chiếc xe đến từ thành phố nào.","fa":"پلاک نشان می دهد که ماشین از کدام شهر آمده است."},{"de":"Nach dem Umzug brauchte er ein neues Nummernschild.","en":"After moving house he needed a new number plate.","ru":"После переезда ему понадобился новый номерной знак.","vi":"Sau khi chuyển đi, anh cần có biển số mới.","fa":"پس از نقل مکان به پلاک جدید نیاز داشت."}]},{"word":"nun","en":"now","ru":"теперь; ну","vi":"bây giờ","fa":"اکنون","examples":[{"de":"Nun müssen wir eine Entscheidung treffen.","en":"Now we have to make a decision.","ru":"Теперь нам нужно принять решение.","vi":"Bây giờ chúng ta phải đưa ra quyết định.","fa":"حالا باید تصمیم بگیریم."},{"de":"Was machen wir nun?","en":"What do we do now?","ru":"Что же нам теперь делать?","vi":"Chúng ta phải làm gì bây giờ?","fa":"حالا چیکار کنیم؟"}]},{"word":"nur","en":"only; just","ru":"только","vi":"chỉ","fa":"فقط","examples":[{"de":"Ich habe nur zehn Euro dabei.","en":"I only have ten euros with me.","ru":"У меня с собой только десять евро.","vi":"Tôi chỉ có mười euro bên mình.","fa":"من فقط ده یورو با خودم دارم."},{"de":"Das war nur ein Scherz.","en":"That was just a joke.","ru":"Это была всего лишь шутка.","vi":"Đó chỉ là một trò đùa thôi.","fa":"این فقط یک شوخی بود."}]},{"word":"nur Bahnhof verstehen","en":"to not understand a thing","ru":"ничего не понимать (как в тумане)","vi":"không hiểu một điều gì đó","fa":"برای نفهمیدن چیزی","examples":[{"de":"Bei dem Vortrag habe ich nur Bahnhof verstanden.","en":"During the lecture I didn't understand a thing.","ru":"На лекции я вообще ничего не понял.","vi":"Trong bài giảng tôi chỉ hiểu ga xe lửa.","fa":"در طول سخنرانی فقط ایستگاه قطار را فهمیدم."}]},{"word":"nutzen","en":"to use","ru":"использовать; пользоваться","vi":"sử dụng","fa":"استفاده کنید","examples":[{"de":"Wir nutzen die Bibliothek regelmäßig.","en":"We use the library regularly.","ru":"Мы регулярно пользуемся библиотекой.","vi":"Chúng tôi sử dụng thư viện thường xuyên.","fa":"ما به طور منظم از کتابخانه استفاده می کنیم."},{"de":"Man sollte die Zeit gut nutzen.","en":"One should use time well.","ru":"Нужно хорошо использовать время.","vi":"Bạn nên sử dụng thời gian thật tốt.","fa":"باید از زمان به خوبی استفاده کرد."}]},{"word":"nützen","en":"to be useful; to benefit","ru":"приносить пользу","vi":"lợi ích","fa":"منفعت","examples":[{"de":"Diese Erfahrung wird dir später nützen.","en":"This experience will benefit you later.","ru":"Этот опыт пригодится тебе позже.","vi":"Kinh nghiệm này sẽ có ích cho bạn sau này.","fa":"این تجربه بعدا برای شما مفید خواهد بود."},{"de":"Es nützt nichts, sich zu beschweren.","en":"It's no use complaining.","ru":"Нет смысла жаловаться.","vi":"Chẳng ích gì khi phàn nàn.","fa":"شکایت فایده ای ندارد"}]},{"word":"der Nutzer","en":"a user of a service or platform","ru":"пользователь (сервиса или платформы)","vi":"người dùng","fa":"the user","examples":[{"de":"Nutzer haben normalerweise viele Posts auf ihrer Pinnwand.","en":"Users normally have lots of posts on their wall.","ru":"У пользователей обычно много постов на стене.","vi":"Người dùng thường có rất nhiều bài viết trên tường của họ.","fa":"کاربران معمولاً تعداد زیادی پست روی دیوار خود دارند."},{"de":"Die App hat inzwischen über eine Million aktive Nutzer.","en":"The app now has over a million active users.","ru":"У приложения теперь более миллиона активных пользователей.","vi":"Ứng dụng này hiện có hơn một triệu người dùng hoạt động.","fa":"این اپلیکیشن اکنون بیش از یک میلیون کاربر فعال دارد."},{"de":"Jeder Nutzer kann sein Profil selbst gestalten.","en":"Every user can design their own profile.","ru":"Каждый пользователь может оформить свой профиль по-своему.","vi":"Mỗi người dùng có thể thiết kế hồ sơ của riêng mình.","fa":"هر کاربر می تواند پروفایل خود را طراحی کند."}]},{"word":"nützlich","en":"useful, helpful","ru":"полезный","vi":"hữu ích","fa":"مفید","examples":[{"de":"Dieses Werkzeug ist sehr nützlich.","en":"This tool is very useful.","ru":"Этот инструмент очень полезен.","vi":"Công cụ này rất hữu ích.","fa":"این ابزار بسیار مفید است."},{"de":"Sie hat mir ein paar nützliche Tipps gegeben.","en":"She gave me a few useful tips.","ru":"Она дала мне несколько полезных советов.","vi":"Cô ấy đã cho tôi một số lời khuyên hữu ích.","fa":"او به من نکات مفیدی داد."},{"de":"Ein Smartphone kann auf Reisen sehr nützlich sein.","en":"A smartphone can be very useful when travelling.","ru":"Смартфон может быть очень полезен в путешествии.","vi":"Một chiếc điện thoại thông minh có thể rất hữu ích khi đi du lịch.","fa":"گوشی هوشمند می تواند در سفر بسیار مفید باشد."}]},{"word":"ob","en":"whether; if","ru":"ли","vi":"liệu","fa":"آیا","examples":[{"de":"Ich weiß nicht, ob er heute kommt.","en":"I don't know whether he's coming today.","ru":"Я не знаю, придёт ли он сегодня.","vi":"Tôi không biết hôm nay anh ấy có đến không.","fa":"نمیدونم امروز میاد یا نه"},{"de":"Frag ihn, ob er Zeit hat.","en":"Ask him if he has time.","ru":"Спроси его, есть ли у него время.","vi":"Hỏi xem anh ấy có thời gian không.","fa":"از او بپرسید که آیا وقت دارد؟"}]},{"word":"obdachlos","en":"homeless","ru":"бездомный","vi":"vô gia cư","fa":"بی خانمان","examples":[{"de":"Zwei Obdachlose schliefen im Park.","en":"Two homeless people were sleeping in the park.","ru":"В парке спали двое бездомных.","vi":"Hai người vô gia cư đang ngủ trong công viên.","fa":"دو بی خانمان در پارک خوابیده بودند."},{"de":"Die Stadt baut neue Unterkünfte für obdachlose Menschen.","en":"The city is building new shelters for homeless people.","ru":"Город строит новые приюты для бездомных.","vi":"Thành phố đang xây dựng nơi ở mới cho người vô gia cư.","fa":"شهر در حال ساخت مسکن جدید برای افراد بی خانمان است."},{"de":"Nach dem Brand war die ganze Familie obdachlos.","en":"After the fire the whole family was homeless.","ru":"После пожара вся семья осталась без крова.","vi":"Sau vụ cháy, cả gia đình trở thành vô gia cư.","fa":"پس از آتش سوزی، تمام خانواده بی خانمان شدند."}]},{"word":"oben","en":"above; upstairs","ru":"наверху","vi":"ở trên","fa":"بالا","examples":[{"de":"Mein Zimmer ist oben im ersten Stock.","en":"My room is upstairs on the first floor.","ru":"Моя комната наверху, на втором этаже.","vi":"Phòng của tôi ở trên lầu một.","fa":"اتاق من طبقه اول است."},{"de":"Schau mal, ganz oben auf dem Berg liegt Schnee.","en":"Look, there's snow right at the top of the mountain.","ru":"Смотри, на самой вершине горы лежит снег.","vi":"Nhìn kìa, có tuyết trên đỉnh núi.","fa":"ببین، بالای کوه برف آمده است."}]},{"word":"der Ober","en":"waiter (in a restaurant)","ru":"официант (в ресторане)","vi":"người phục vụ","fa":"گارسون","examples":[{"de":"Der Ober brachte uns die Speisekarte.","en":"The waiter brought us the menu.","ru":"Официант принёс нам меню.","vi":"Người phục vụ đưa cho chúng tôi thực đơn.","fa":"گارسون منو برای ما آورد."},{"de":"Herr Ober, könnten wir bitte zahlen?","en":"Waiter, could we pay please?","ru":"Официант, можно нам рассчитаться?","vi":"Người phục vụ, chúng tôi có thể trả tiền được không?","fa":"گارسون، لطفاً می توانیم پرداخت کنیم؟"},{"de":"Der Ober empfahl uns das Gericht des Tages.","en":"The waiter recommended the dish of the day to us.","ru":"Официант посоветовал нам блюдо дня.","vi":"Người phục vụ giới thiệu món ăn trong ngày cho chúng tôi.","fa":"گارسون غذای روز را به ما توصیه کرد."}]},{"word":"ober-","en":"upper, top, chief (prefix)","ru":"верхний, высший, главный (приставка)","vi":"phía trên","fa":"بالا","examples":[{"de":"Die oberste Etage hat den schönsten Ausblick.","en":"The top floor has the nicest view.","ru":"С верхнего этажа самый красивый вид.","vi":"Tầng cao nhất có view đẹp nhất.","fa":"طبقه آخر زیباترین منظره را دارد."},{"de":"Sein Büro liegt im obersten Stockwerk.","en":"His office is on the topmost floor.","ru":"Его кабинет на самом верхнем этаже.","vi":"Văn phòng của anh ấy ở trên tầng cao nhất.","fa":"دفترش در طبقه بالاست."},{"de":"Die Oberfläche des Sees war ganz ruhig.","en":"The surface of the lake was completely calm.","ru":"Поверхность озера была совершенно спокойной.","vi":"Mặt hồ hoàn toàn yên tĩnh.","fa":"سطح دریاچه کاملا آرام بود."}]},{"word":"die Oberfläche","en":"interface; surface","ru":"интерфейс; поверхность","vi":"bề mặt","fa":"سطح","examples":[{"de":"Die Oberfläche des Programms ist sehr übersichtlich.","en":"The program's interface is very clear.","ru":"Интерфейс программы очень наглядный.","vi":"Giao diện của chương trình rất rõ ràng.","fa":"رابط برنامه بسیار واضح است."},{"de":"An die neue Oberfläche muss ich mich erst gewöhnen.","en":"I first have to get used to the new interface.","ru":"К новому интерфейсу мне ещё нужно привыкнуть.","vi":"Tôi phải làm quen với giao diện mới.","fa":"باید به اینترفیس جدید عادت کنم."},{"de":"Du kannst die Farben der Oberfläche selbst wählen.","en":"You can choose the colours of the interface yourself.","ru":"Ты можешь сам выбрать цвета интерфейса.","vi":"Bạn có thể tự mình chọn màu sắc của bề mặt.","fa":"شما می توانید رنگ های سطح را خودتان انتخاب کنید."}]},{"word":"der Oberkörper","en":"upper body, torso","ru":"верхняя часть тела, корпус, торс","vi":"phần thân trên","fa":"بالاتنه","examples":[{"de":"Drehe den Oberkörper langsam nach rechts.","en":"Slowly turn your upper body to the right.","ru":"Медленно поверни корпус вправо.","vi":"Từ từ xoay phần thân trên của bạn sang bên phải.","fa":"به آرامی بالاتنه خود را به سمت راست بچرخانید."},{"de":"Beim Vorbeugen senkst du den Oberkörper zu den Beinen.","en":"When bending forward you lower your upper body towards your legs.","ru":"При наклоне вперёд ты опускаешь корпус к ногам.","vi":"Khi cúi về phía trước, hạ thấp phần thân trên về phía chân.","fa":"هنگام خم شدن به جلو، بالاتنه خود را به سمت پاهایتان پایین بیاورید."},{"de":"Der Oberkörper bleibt während der Übung aufrecht.","en":"The upper body stays upright during the exercise.","ru":"Во время упражнения корпус остаётся прямым.","vi":"Phần thân trên vẫn giữ thẳng trong khi tập.","fa":"بالاتنه در طول تمرین عمودی باقی می ماند."}]},{"word":"das Obers","en":"cream (Austrian German)","ru":"сливки (австрийский вариант немецкого)","vi":"kem","fa":"کرم","examples":[{"de":"In Österreich bestellt man Kaffee oft mit Obers.","en":"In Austria you often order coffee with cream.","ru":"В Австрии часто заказывают кофе со сливками.","vi":"Ở Áo bạn thường gọi cà phê với kem.","fa":"در اتریش اغلب قهوه با خامه سفارش می دهید."},{"de":"Sie schlug das Obers für die Torte steif.","en":"She whipped the cream stiff for the cake.","ru":"Она взбила сливки для торта до крепкой пены.","vi":"Cô đánh kem cho chiếc bánh cho đến khi cứng lại.","fa":"او خامه کیک را هم زد تا سفت شود."},{"de":"Möchtest du ein wenig Obers auf deinen Kuchen?","en":"Would you like a little cream on your cake?","ru":"Хочешь немного сливок к пирогу?","vi":"Bạn có muốn một ít kem trên bánh của bạn?","fa":"آیا می خواهید کمی خامه روی کیک خود داشته باشید؟"}]},{"word":"das Obst","en":"fruit","ru":"фрукты","vi":"trái cây","fa":"میوه","examples":[{"de":"Ich esse jeden Tag frisches Obst.","en":"I eat fresh fruit every day.","ru":"Я каждый день ем свежие фрукты.","vi":"I eat fresh fruit every day.","fa":"من هر روز میوه تازه می خورم."},{"de":"Auf dem Markt gibt es viel Obst und Gemüse.","en":"There is a lot of fruit and vegetables at the market.","ru":"На рынке много фруктов и овощей.","vi":"Có rất nhiều trái cây và rau quả trên thị trường.","fa":"میوه ها و سبزیجات زیادی در بازار وجود دارد."}]},{"word":"obwohl","en":"although","ru":"хотя","vi":"mặc dù","fa":"اگرچه","examples":[{"de":"Obwohl es regnet, gehen wir spazieren.","en":"Although it's raining, we're going for a walk.","ru":"Хотя идёт дождь, мы идём гулять.","vi":"Nếu bạn muốn đăng ký, bạn sẽ có được không gian rộng rãi.","fa":"با وجود اینکه باران می بارد، میریم پیاده روی."},{"de":"Er ist zur Arbeit gegangen, obwohl er krank war.","en":"He went to work, although he was sick.","ru":"Он пошёл на работу, хотя был болен.","vi":"Anh ấy đi làm mặc dù anh ấy bị ốm.","fa":"با اینکه مریض بود سر کار رفت."}]},{"word":"oder","en":"or","ru":"или","vi":"hoặc","fa":"یا","examples":[{"de":"Möchtest du Tee oder Kaffee?","en":"Would you like tea or coffee?","ru":"Хочешь чай или кофе?","vi":"Bạn muốn uống trà hay cà phê?","fa":"آیا چای یا قهوه میل دارید؟"},{"de":"Kommst du mit, oder bleibst du zu Hause?","en":"Are you coming with us, or are you staying home?","ru":"Ты идёшь с нами или остаёшься дома?","vi":"Bạn sẽ đi cùng chúng tôi hay bạn đang ở nhà?","fa":"با ما می آیی یا در خانه می مانی؟"}]},{"word":"offen","en":"open","ru":"открытый","vi":"mở","fa":"باز کردن","examples":[{"de":"Die Tür ist offen, du kannst reinkommen.","en":"The door is open, you can come in.","ru":"Дверь открыта, можешь войти.","vi":"Cửa đang mở, bạn có thể vào.","fa":"در باز است، می توانید وارد شوید."},{"de":"Der Laden hat bis 20 Uhr offen.","en":"The shop is open until 8 pm.","ru":"Магазин открыт до 20 часов.","vi":"The shop is open until 8 p.m.","fa":"مغازه تا ساعت 8 شب باز است."}]},{"word":"offenbar","en":"apparently","ru":"очевидно; по-видимому","vi":"rõ ràng","fa":"ظاهرا","examples":[{"de":"Offenbar hat er den Termin vergessen.","en":"Apparently he forgot the appointment.","ru":"Очевидно, он забыл о встрече.","vi":"Offenbar hat er den Termin Vergessen.","fa":"ظاهراً قرار ملاقات را فراموش کرده است."},{"de":"Sie ist offenbar schon nach Hause gegangen.","en":"She has apparently already gone home.","ru":"Она, по-видимому, уже ушла домой.","vi":"Có vẻ như cô ấy đã về nhà rồi.","fa":"ظاهراً او قبلاً به خانه رفته است."}]},{"word":"offensichtlich","en":"obvious; apparently","ru":"очевидный; очевидно","vi":"rõ ràng","fa":"بدیهی است","examples":[{"de":"Es war offensichtlich, dass er log.","en":"It was obvious that he was lying.","ru":"Было очевидно, что он лжёт.","vi":"Rõ ràng là anh ta đang nói dối.","fa":"معلوم بود که داره دروغ میگه"},{"de":"Offensichtlich hat sie den Termin vergessen.","en":"Apparently she forgot the appointment.","ru":"Очевидно, она забыла о встрече.","vi":"Có vẻ như cô ấy đã quên cuộc hẹn.","fa":"ظاهراً قرار ملاقات را فراموش کرده است."}]},{"word":"öffentlich","en":"public","ru":"общественный; публичный","vi":"công khai","fa":"عمومی","examples":[{"de":"Ich fahre meistens mit öffentlichen Verkehrsmitteln.","en":"I mostly travel by public transport.","ru":"Я в основном езжу на общественном транспорте.","vi":"Tôi chủ yếu đi phương tiện công cộng.","fa":"من بیشتر از وسایل نقلیه عمومی استفاده می کنم."},{"de":"Das Konzert findet auf einem öffentlichen Platz statt.","en":"The concert takes place in a public square.","ru":"Концерт проходит на общественной площади.","vi":"The concert takes place in a public square.","fa":"کنسرت در یک میدان عمومی برگزار می شود."}]},{"word":"die Öffentlichkeit","en":"the public","ru":"общественность","vi":"công chúng","fa":"عمومی","examples":[{"de":"Der Politiker trat vor die Öffentlichkeit.","en":"The politician appeared before the public.","ru":"Политик выступил перед общественностью.","vi":"Chính trị gia xuất hiện trước công chúng.","fa":"این سیاستمدار در برابر مردم ظاهر شد."},{"de":"Diese Information ist nicht für die Öffentlichkeit bestimmt.","en":"This information is not intended for the public.","ru":"Эта информация не предназначена для общественности.","vi":"Thông tin này không dành cho công chúng.","fa":"این اطلاعات برای عموم در نظر گرفته نشده است."}]},{"word":"offiziell","en":"official","ru":"официальный","vi":"chính thức","fa":"رسمی","examples":[{"de":"Die offizielle Eröffnung ist am Samstag.","en":"The official opening is on Saturday.","ru":"Официальное открытие состоится в субботу.","vi":"Ngày khai mạc chính thức là vào thứ bảy.","fa":"افتتاحیه رسمی روز شنبه است."},{"de":"Das ist noch keine offizielle Entscheidung.","en":"That is not an official decision yet.","ru":"Это ещё не официальное решение.","vi":"Đây vẫn chưa phải là quyết định chính thức.","fa":"این هنوز یک تصمیم رسمی نیست."}]},{"word":"öffnen","en":"to open","ru":"открывать","vi":"mở","fa":"باز کردن","examples":[{"de":"Kannst du bitte das Fenster öffnen?","en":"Can you please open the window?","ru":"Можешь открыть окно, пожалуйста?","vi":"Bạn có thể vui lòng mở cửa sổ được không?","fa":"میشه لطفا پنجره رو باز کن"},{"de":"Die Bank öffnet um neun Uhr.","en":"The bank opens at nine o'clock.","ru":"Банк открывается в девять часов.","vi":"Ngân hàng mở cửa lúc chín giờ.","fa":"بانک ساعت نه باز می شود."}]},{"word":"oft","en":"often","ru":"часто","vi":"thường xuyên","fa":"اغلب","examples":[{"de":"Ich gehe oft ins Kino.","en":"I often go to the cinema.","ru":"Я часто хожу в кино.","vi":"Tôi thường đi xem phim.","fa":"من اغلب به سینما می روم."},{"de":"Wie oft trainierst du in der Woche?","en":"How often do you train per week?","ru":"Как часто ты тренируешься в неделю?","vi":"Bạn tập luyện bao nhiêu lần một tuần?","fa":"چند بار در هفته تمرین می کنید؟"}]},{"word":"öfter","en":"more often, quite often","ru":"чаще, почаще","vi":"thường xuyên hơn","fa":"بیشتر اوقات","examples":[{"de":"Wir sollten uns öfter sehen.","en":"We should see each other more often.","ru":"Нам стоит видеться почаще.","vi":"Chúng ta nên gặp nhau thường xuyên hơn.","fa":"باید بیشتر همو ببینیم"},{"de":"In letzter Zeit bin ich öfter krank.","en":"Lately I have been ill more often.","ru":"В последнее время я чаще болею.","vi":"Gần đây tôi bị ốm rất nhiều.","fa":"من اخیراً خیلی مریض شده ام."},{"de":"Das passiert mir öfter, als mir lieb ist.","en":"That happens to me more often than I'd like.","ru":"Это случается со мной чаще, чем хотелось бы.","vi":"Điều này xảy ra với tôi thường xuyên hơn tôi muốn.","fa":"این برای من بیشتر از آنچه که دوست دارم اتفاق می افتد."}]},{"word":"ohne","en":"without","ru":"без","vi":"không có","fa":"بدون","examples":[{"de":"Ich trinke meinen Kaffee ohne Zucker.","en":"I drink my coffee without sugar.","ru":"Я пью кофе без сахара.","vi":"Tôi uống cà phê không đường.","fa":"من قهوه ام را بدون قند می نوشم."},{"de":"Ohne dich wäre die Party langweilig gewesen.","en":"Without you the party would have been boring.","ru":"Без тебя вечеринка была бы скучной.","vi":"Nếu không có bạn bữa tiệc sẽ trở nên nhàm chán.","fa":"بدون شما مهمانی خسته کننده بود."}]},{"word":"das Ohr","en":"ear","ru":"ухо","vi":"cái tai","fa":"گوش","examples":[{"de":"Mir tut das Ohr weh.","en":"My ear hurts.","ru":"У меня болит ухо.","vi":"Tai tôi đau quá.","fa":"گوشم درد میکنه"},{"de":"Er hat sich die Ohren zugehalten, weil es so laut war.","en":"He covered his ears because it was so loud.","ru":"Он закрыл уши, потому что было так громко.","vi":"Anh bịt tai lại vì quá ồn ào.","fa":"چون صدایش خیلی بلند بود گوش هایش را گرفت."}]},{"word":"die Ohren spitzen","en":"to prick up one's ears (listen closely)","ru":"навострить уши (внимательно слушать)","vi":"vểnh tai lên","fa":"گوش تیز کردن","examples":[{"de":"Als sein Name fiel, spitzte er die Ohren.","en":"When his name was mentioned, he pricked up his ears.","ru":"Когда прозвучало его имя, он навострил уши.","vi":"Khi nhắc đến tên anh, tai anh vểnh lên.","fa":"وقتی اسمش به میان آمد، گوش هایش بلند شد."}]},{"word":"öko-","en":"eco- (prefix relating to ecology/environment)","ru":"эко- (приставка: связанный с экологией, окружающей средой)","vi":"sinh thái","fa":"محیط زیست","examples":[{"de":"Im Supermarkt findet man immer mehr Öko-Produkte.","en":"In the supermarket you find more and more eco products.","ru":"В супермаркете всё больше эко-продуктов.","vi":"Bạn có thể tìm thấy ngày càng nhiều sản phẩm hữu cơ trong siêu thị.","fa":"شما می توانید محصولات ارگانیک بیشتری را در سوپرمارکت ها پیدا کنید."},{"de":"Sie achtet beim Einkaufen auf den Öko-Standard.","en":"When shopping she pays attention to the eco standard.","ru":"При покупках она обращает внимание на эко-стандарт.","vi":"Cô chú ý đến tiêu chuẩn hữu cơ khi mua sắm.","fa":"او هنگام خرید به استانداردهای ارگانیک توجه می کند."},{"de":"Das Hotel wirbt mit seinem Öko-Konzept.","en":"The hotel advertises its eco concept.","ru":"Отель рекламирует свою эко-концепцию.","vi":"Khách sạn quảng cáo khái niệm sinh thái của nó.","fa":"این هتل مفهوم اکو خود را تبلیغ می کند."}]},{"word":"Öko- (ökologisch)","en":"eco- (ecological)","ru":"эко- (экологический)","vi":"eco- (sinh thái)","fa":"زیست محیطی (اکولوژیک)","examples":[{"de":"Wir kaufen gern Ökoprodukte im Bioladen.","en":"We like to buy eco products at the organic shop.","ru":"Мы любим покупать эко-продукты в магазине органических товаров.","vi":"Chúng tôi thích mua sản phẩm hữu cơ ở các cửa hàng hữu cơ.","fa":"ما دوست داریم محصولات ارگانیک را در فروشگاه های ارگانیک بخریم."},{"de":"Ökologisches Handeln ist heute sehr wichtig.","en":"Ecological behavior is very important today.","ru":"Экологичное поведение сегодня очень важно.","vi":"Hành động sinh thái ngày nay rất quan trọng.","fa":"اقدامات زیست محیطی امروزه بسیار مهم است."}]},{"word":"ökologisch","en":"ecological, environmentally friendly","ru":"экологический, экологичный","vi":"sinh thái","fa":"زیست محیطی","examples":[{"de":"Wir versuchen, möglichst ökologisch zu leben.","en":"We try to live as ecologically as possible.","ru":"Мы стараемся жить как можно экологичнее.","vi":"Chúng tôi cố gắng sống sinh thái nhất có thể.","fa":"ما سعی می کنیم تا حد امکان زیست محیطی زندگی کنیم."},{"de":"Die Verpackung ist aus ökologischen Materialien.","en":"The packaging is made of ecological materials.","ru":"Упаковка сделана из экологичных материалов.","vi":"Bao bì được làm bằng vật liệu sinh thái.","fa":"بسته بندی از مواد زیست محیطی ساخته شده است."},{"de":"Das Projekt hat einen großen ökologischen Nutzen.","en":"The project has a great ecological benefit.","ru":"У проекта большая экологическая польза.","vi":"Dự án mang lại lợi ích sinh thái to lớn.","fa":"این پروژه مزایای زیست محیطی زیادی دارد."}]},{"word":"der Ökostrom","en":"green electricity","ru":"зелёная электроэнергия, электричество из возобновляемых источников","vi":"điện xanh","fa":"برق سبز","examples":[{"de":"Wir beziehen seit einem Jahr nur noch Ökostrom.","en":"For a year now we have only been getting green electricity.","ru":"Вот уже год мы получаем только зелёную электроэнергию.","vi":"Chúng tôi mới sử dụng điện xanh được một năm nay.","fa":"الان فقط یک سال است که از برق سبز استفاده می کنیم."},{"de":"Ökostrom kommt aus Sonne, Wind und Wasser.","en":"Green electricity comes from sun, wind and water.","ru":"Зелёная электроэнергия приходит от солнца, ветра и воды.","vi":"Điện xanh đến từ mặt trời, gió và nước.","fa":"برق سبز از خورشید، باد و آب می آید."},{"de":"Viele Anbieter werben heute mit Ökostrom.","en":"Many providers now advertise with green electricity.","ru":"Многие поставщики сегодня рекламируют зелёную электроэнергию.","vi":"Nhiều nhà cung cấp ngày nay quảng cáo bằng điện xanh.","fa":"امروزه بسیاری از ارائه دهندگان با برق سبز تبلیغ می کنند."}]},{"word":"das Öl","en":"oil","ru":"масло; нефть","vi":"dầu","fa":"روغن","examples":[{"de":"Gib etwas Öl in die Pfanne.","en":"Put some oil in the pan.","ru":"Налей немного масла на сковороду.","vi":"Thêm một ít dầu vào chảo.","fa":"مقداری روغن به تابه اضافه کنید."},{"de":"Der Preis für Öl ist gestiegen.","en":"The price of oil has risen.","ru":"Цена на нефть выросла.","vi":"Giá dầu đã tăng.","fa":"قیمت نفت افزایش یافته است."}]},{"word":"Öl ins Feuer gießen","en":"to add fuel to the fire","ru":"подливать масла в огонь","vi":"đổ thêm dầu vào lửa","fa":"برای افزودن هیزم به آتش","examples":[{"de":"Mit dieser Bemerkung hat er nur Öl ins Feuer gegossen.","en":"With that remark he only added fuel to the fire.","ru":"Этой репликой он только подлил масла в огонь.","vi":"Với nhận xét này, anh ta chỉ đổ thêm dầu vào lửa.","fa":"با این اظهارات فقط هیزمی به آتش زد."}]},{"word":"der Olympiasieger","en":"Olympic champion (male)","ru":"олимпийский чемпион (мужчина)","vi":"nhà vô địch Olympic","fa":"قهرمان المپیک","examples":[{"de":"Er wurde mit zwanzig Jahren Olympiasieger im Schwimmen.","en":"He became Olympic champion in swimming at the age of twenty.","ru":"В двадцать лет он стал олимпийским чемпионом по плаванию.","vi":"Anh trở thành nhà vô địch bơi lội Olympic ở tuổi hai mươi.","fa":"او در بیست سالگی قهرمان شنای المپیک شد."},{"de":"Der Olympiasieger trainiert jeden Tag mehrere Stunden.","en":"The Olympic champion trains for several hours every day.","ru":"Олимпийский чемпион каждый день тренируется по несколько часов.","vi":"Nhà vô địch Olympic tập luyện vài giờ mỗi ngày.","fa":"قهرمان المپیک هر روز چندین ساعت تمرین می کند."},{"de":"Als Olympiasieger ist er in seinem Land sehr berühmt.","en":"As an Olympic champion he is very famous in his country.","ru":"Как олимпийский чемпион он очень известен в своей стране.","vi":"Là nhà vô địch Olympic, anh ấy rất nổi tiếng ở đất nước mình.","fa":"او به عنوان یک قهرمان المپیک در کشورش بسیار مشهور است."}]},{"word":"olympisch","en":"Olympic (as in the Olympic Games)","ru":"олимпийский (относящийся к Олимпийским играм)","vi":"Olympic","fa":"المپیک","examples":[{"de":"Die Olympischen Spiele finden alle vier Jahre statt.","en":"The Olympic Games take place every four years.","ru":"Олимпийские игры проходят раз в четыре года.","vi":"Thế vận hội Olympic diễn ra bốn năm một lần.","fa":"بازی های المپیک هر چهار سال یکبار برگزار می شود."},{"de":"Sie nahm an den Olympischen Winterspielen teil.","en":"She took part in the Winter Olympic Games.","ru":"Она участвовала в зимних Олимпийских играх.","vi":"Cô đã tham gia Thế vận hội mùa đông.","fa":"او در بازی های المپیک زمستانی شرکت کرد."},{"de":"Bei den Olympischen Spielen treten Athleten aus aller Welt an.","en":"At the Olympic Games, athletes from all over the world compete.","ru":"На Олимпийских играх соревнуются спортсмены со всего мира.","vi":"Các vận động viên từ khắp nơi trên thế giới tranh tài tại Thế vận hội Olympic.","fa":"ورزشکاران از سراسر جهان در بازی های المپیک شرکت می کنند."}]},{"word":"die Oma","en":"grandma","ru":"бабушка","vi":"bà ngoại","fa":"مادربزرگ","examples":[{"de":"Meine Oma backt jeden Sonntag einen Kuchen.","en":"My grandma bakes a cake every Sunday.","ru":"Моя бабушка печёт пирог каждое воскресенье.","vi":"Bà tôi nướng bánh vào mỗi Chủ Nhật.","fa":"مادربزرگ من هر یکشنبه یک کیک می پزد."},{"de":"Wir besuchen unsere Oma am Wochenende.","en":"We visit our grandma on the weekend.","ru":"Мы навещаем бабушку на выходных.","vi":"Chúng tôi đến thăm bà của chúng tôi vào cuối tuần.","fa":"آخر هفته به دیدن مادربزرگمان می رویم."}]},{"word":"der Onkel","en":"uncle","ru":"дядя","vi":"chú","fa":"عمو","examples":[{"de":"Mein Onkel lebt in Kanada.","en":"My uncle lives in Canada.","ru":"Мой дядя живёт в Канаде.","vi":"Chú tôi sống ở Canada.","fa":"دایی من در کانادا زندگی می کند."},{"de":"Ich habe von meinem Onkel ein Geschenk bekommen.","en":"I got a gift from my uncle.","ru":"Я получил подарок от дяди.","vi":"Tôi đã nhận được một món quà từ chú tôi.","fa":"از عمویم هدیه گرفتم."}]},{"word":"der Onlineshop","en":"online shop","ru":"интернет-магазин","vi":"cửa hàng trực tuyến","fa":"فروشگاه آنلاین","examples":[{"de":"Diese Schuhe habe ich in einem Onlineshop gekauft.","en":"I bought these shoes in an online shop.","ru":"Эти туфли я купила в интернет-магазине.","vi":"Tôi đã mua đôi giày này từ một cửa hàng trực tuyến.","fa":"من این کفش ها را از یک فروشگاه اینترنتی خریدم."},{"de":"Der Onlineshop liefert die Ware innerhalb von zwei Tagen.","en":"The online shop delivers the goods within two days.","ru":"Интернет-магазин доставляет товар в течение двух дней.","vi":"Cửa hàng trực tuyến giao hàng trong vòng hai ngày.","fa":"فروشگاه اینترنتی کالا را ظرف دو روز تحویل می دهد."},{"de":"In diesem Onlineshop sind die Preise besonders günstig.","en":"In this online shop the prices are particularly cheap.","ru":"В этом интернет-магазине особенно низкие цены.","vi":"Giá trong cửa hàng trực tuyến này đặc biệt thấp.","fa":"قیمت ها در این فروشگاه آنلاین به خصوص پایین است."}]},{"word":"das Onlineshopping","en":"online shopping","ru":"покупки в интернете, онлайн-шопинг","vi":"mua sắm trực tuyến","fa":"خرید آنلاین","examples":[{"de":"Onlineshopping ist bei jungen Leuten sehr beliebt.","en":"Online shopping is very popular among young people.","ru":"Онлайн-шопинг очень популярен среди молодёжи.","vi":"Mua sắm trực tuyến đang rất được giới trẻ ưa chuộng.","fa":"خرید اینترنتی در بین جوانان بسیار محبوب است."},{"de":"Beim Onlineshopping spare ich oft viel Zeit.","en":"When online shopping I often save a lot of time.","ru":"Покупая в интернете, я часто экономлю много времени.","vi":"Tôi thường tiết kiệm được rất nhiều thời gian khi mua sắm trực tuyến.","fa":"من اغلب هنگام خرید آنلاین زمان زیادی را صرفه جویی می کنم."},{"de":"Onlineshopping hat aber auch Nachteile, etwa lange Lieferzeiten.","en":"Online shopping also has disadvantages, such as long delivery times.","ru":"У онлайн-шопинга есть и недостатки, например, долгая доставка.","vi":"Nhưng mua sắm trực tuyến cũng có nhược điểm như thời gian giao hàng lâu.","fa":"اما خرید اینترنتی معایبی نیز دارد که از جمله آن می توان به طولانی بودن زمان تحویل اشاره کرد."}]},{"word":"der Opa","en":"grandpa","ru":"дедушка","vi":"ông nội","fa":"پدربزرگ","examples":[{"de":"Mein Opa erzählt gerne Geschichten aus seiner Jugend.","en":"My grandpa likes to tell stories from his youth.","ru":"Мой дедушка любит рассказывать истории из своей молодости.","vi":"Ông tôi thích kể những câu chuyện thời trẻ.","fa":"پدربزرگم دوست دارد از دوران جوانی اش قصه بگوید."},{"de":"Der Opa spielt mit den Enkelkindern im Garten.","en":"Grandpa plays with the grandchildren in the garden.","ru":"Дедушка играет с внуками в саду.","vi":"Ông nội chơi với các cháu trong vườn.","fa":"پدربزرگ با نوه هایش در باغ بازی می کند."}]},{"word":"die Oper","en":"opera","ru":"опера","vi":"vở opera","fa":"اپرا","examples":[{"de":"Am Samstag gehen wir in die Oper.","en":"On Saturday we're going to the opera.","ru":"В субботу мы идём в оперу.","vi":"Vào thứ bảy chúng tôi đi xem opera.","fa":"شنبه می رویم اپرا."},{"de":"Diese Oper von Mozart ist sehr bekannt.","en":"This opera by Mozart is very famous.","ru":"Эта опера Моцарта очень известна.","vi":"Vở opera này của Mozart rất nổi tiếng.","fa":"این اپرای موتسارت بسیار شناخته شده است."}]},{"word":"die Operation","en":"operation; surgery","ru":"операция (хирургическая)","vi":"hoạt động","fa":"عملیات","examples":[{"de":"Die Operation hat drei Stunden gedauert.","en":"The operation lasted three hours.","ru":"Операция длилась три часа.","vi":"Ca phẫu thuật kéo dài ba giờ.","fa":"این عملیات سه ساعت طول کشید."},{"de":"Nach der Operation muss er sich ausruhen.","en":"After the operation he has to rest.","ru":"После операции ему нужно отдыхать.","vi":"Sau ca phẫu thuật, anh ấy cần được nghỉ ngơi.","fa":"بعد از عمل نیاز به استراحت دارد."},{"de":"Der Arzt erklärte mir die geplante Operation genau.","en":"The doctor explained the planned operation to me in detail.","ru":"Врач подробно объяснил мне планируемую операцию.","vi":"Bác sĩ giải thích chi tiết về kế hoạch phẫu thuật cho tôi.","fa":"دکتر عملیات برنامه ریزی شده را با جزئیات برایم توضیح داد."}]},{"word":"operieren","en":"to operate (surgically)","ru":"оперировать","vi":"vận hành","fa":"عمل کنند","examples":[{"de":"Der Arzt muss den Patienten sofort operieren.","en":"The doctor has to operate on the patient immediately.","ru":"Врач должен немедленно прооперировать пациента.","vi":"Bác sĩ phải phẫu thuật cho bệnh nhân ngay lập tức.","fa":"پزشک باید بلافاصله بیمار را جراحی کند."},{"de":"Sie wurde letzte Woche am Knie operiert.","en":"She had knee surgery last week.","ru":"На прошлой неделе ей сделали операцию на колене.","vi":"Cô ấy đã phẫu thuật đầu gối vào tuần trước.","fa":"او هفته گذشته زانو را جراحی کرد."}]},{"word":"das Opfer","en":"victim; sacrifice","ru":"жертва","vi":"nạn nhân","fa":"قربانی","examples":[{"de":"Die Feuerwehr rettete alle Opfer des Unfalls.","en":"The fire brigade rescued all victims of the accident.","ru":"Пожарные спасли всех жертв аварии.","vi":"Lực lượng cứu hỏa đã giải cứu toàn bộ nạn nhân trong vụ tai nạn.","fa":"آتش نشانی تمامی مصدومان این حادثه را نجات داد."},{"de":"Für ihren Erfolg musste sie viele Opfer bringen.","en":"She had to make many sacrifices for her success.","ru":"Ради своего успеха ей пришлось пойти на многие жертвы.","vi":"Cô đã phải hy sinh rất nhiều để có được thành công.","fa":"او باید برای موفقیتش فداکاری های زیادی می کرد."}]},{"word":"die Opposition","en":"opposition","ru":"оппозиция","vi":"sự phản đối","fa":"the opposition","examples":[{"de":"Die Opposition kritisiert die Pläne der Regierung scharf.","en":"The opposition sharply criticises the government's plans.","ru":"Оппозиция резко критикует планы правительства.","vi":"Phe đối lập chỉ trích gay gắt các kế hoạch của chính phủ.","fa":"مخالفان به شدت از برنامه های دولت انتقاد می کنند."},{"de":"Nach der Wahl sitzt die alte Partei in der Opposition.","en":"After the election the old party sits in opposition.","ru":"После выборов старая партия оказалась в оппозиции.","vi":"Sau cuộc bầu cử, đảng cũ ở phe đối lập.","fa":"پس از انتخابات، حزب قدیمی در اپوزیسیون است."},{"de":"Die Opposition forderte eine neue Abstimmung.","en":"The opposition demanded a new vote.","ru":"Оппозиция потребовала нового голосования.","vi":"Phe đối lập kêu gọi một cuộc bỏ phiếu mới.","fa":"مخالفان خواستار رای گیری جدید شدند."}]},{"word":"optimistisch","en":"optimistic","ru":"оптимистичный","vi":"lạc quan","fa":"خوش بینانه","examples":[{"de":"Trotz der Probleme bleibt er optimistisch.","en":"Despite the problems, he remains optimistic.","ru":"Несмотря на проблемы, он остаётся оптимистичным.","vi":"Bất chấp những vấn đề, anh vẫn lạc quan.","fa":"با وجود مشکلات، او همچنان خوشبین است."},{"de":"Ich bin optimistisch, dass wir die Prüfung schaffen.","en":"I'm optimistic that we'll pass the exam.","ru":"Я оптимистично настроен, что мы сдадим экзамен.","vi":"Tôi lạc quan rằng chúng tôi sẽ vượt qua kỳ thi.","fa":"من خوشبین هستم که در این آزمون موفق شویم."}]},{"word":"die Orange","en":"orange (fruit)","ru":"апельсин","vi":"quả cam","fa":"پرتقال","examples":[{"de":"Zum Frühstück esse ich gern eine Orange.","en":"For breakfast I like to eat an orange.","ru":"На завтрак я люблю есть апельсин.","vi":"Tôi thích ăn một quả cam vào bữa sáng.","fa":"من دوست دارم صبحانه یک پرتقال بخورم."},{"de":"Die Orangen aus Spanien schmecken sehr süß.","en":"The oranges from Spain taste very sweet.","ru":"Апельсины из Испании очень сладкие на вкус.","vi":"Cam từ Tây Ban Nha có vị rất ngọt.","fa":"پرتقال های اسپانیایی طعم بسیار شیرینی دارند."}]},{"word":"das Orchester","en":"orchestra","ru":"оркестр","vi":"dàn nhạc","fa":"ارکستر","examples":[{"de":"Das Orchester spielt heute Abend im Konzertsaal.","en":"The orchestra is playing tonight in the concert hall.","ru":"Оркестр играет сегодня вечером в концертном зале.","vi":"Dàn nhạc đang chơi trong phòng hòa nhạc tối nay.","fa":"این ارکستر عصر امروز در سالن کنسرت می نوازد."},{"de":"Sie spielt Geige in einem bekannten Orchester.","en":"She plays violin in a famous orchestra.","ru":"Она играет на скрипке в известном оркестре.","vi":"Cô chơi violin trong một dàn nhạc nổi tiếng.","fa":"او در یک ارکستر معروف ویولن می نوازد."}]},{"word":"ordentlich","en":"tidy; neat","ru":"аккуратный; опрятный","vi":"gọn gàng","fa":"مرتب","examples":[{"de":"Bitte räum dein Zimmer ordentlich auf.","en":"Please tidy up your room neatly.","ru":"Пожалуйста, аккуратно убери свою комнату.","vi":"Hãy dọn dẹp phòng của bạn đúng cách.","fa":"لطفا اتاق خود را به درستی مرتب کنید."},{"de":"Er ist immer sehr ordentlich gekleidet.","en":"He is always dressed very neatly.","ru":"Он всегда одет очень опрятно.","vi":"Anh ấy luôn ăn mặc rất gọn gàng.","fa":"او همیشه خیلی مرتب لباس می پوشد."}]},{"word":"die Ordination","en":"doctor's office/practice (Austrian)","ru":"врачебный кабинет (австр.)","vi":"phòng khám bác sĩ","fa":"مطب پزشک","examples":[{"de":"Die Ordination des Arztes ist von acht bis zwölf Uhr geöffnet.","en":"The doctor's office is open from eight to twelve.","ru":"Врачебный кабинет открыт с восьми до двенадцати часов.","vi":"Văn phòng bác sĩ mở cửa từ tám giờ sáng đến mười hai giờ tối.","fa":"مطب دکتر از هشت صبح تا دوازده شب باز است."},{"de":"Ich habe heute einen Termin in der Ordination.","en":"I have an appointment at the doctor's office today.","ru":"У меня сегодня приём в врачебном кабинете.","vi":"Hôm nay tôi có hẹn ở văn phòng.","fa":"امروز در دفتر قرار دارم."}]},{"word":"ordnen","en":"to arrange; to put in order","ru":"упорядочивать; приводить в порядок","vi":"sắp xếp","fa":"ترتیب دهید","examples":[{"de":"Sie ordnet die Bücher nach dem Alphabet.","en":"She arranges the books alphabetically.","ru":"Она расставляет книги по алфавиту.","vi":"Cô sắp xếp sách theo bảng chữ cái.","fa":"او کتاب ها را بر اساس حروف الفبا مرتب می کند."},{"de":"Ich muss meine Unterlagen noch ordnen.","en":"I still need to sort out my documents.","ru":"Мне ещё нужно привести в порядок свои документы.","vi":"Tôi vẫn phải sắp xếp tài liệu của mình.","fa":"من هنوز باید مدارکم را مرتب کنم."}]},{"word":"die Ordnung","en":"order, tidiness","ru":"порядок","vi":"thứ tự","fa":"سفارش","examples":[{"de":"In meinem Zimmer herrscht endlich wieder Ordnung.","en":"There is finally order in my room again.","ru":"В моей комнате наконец снова порядок.","vi":"Phòng của tôi cuối cùng đã ổn định trở lại.","fa":"بالاخره اتاقم دوباره مرتب شد."},{"de":"Sie hält in der Küche immer große Ordnung.","en":"She always keeps the kitchen very tidy.","ru":"На кухне она всегда поддерживает идеальный порядок.","vi":"Cô ấy luôn giữ nhà bếp gọn gàng.","fa":"او همیشه آشپزخانه را مرتب نگه می دارد."},{"de":"Bring bitte deine Sachen in Ordnung, bevor du gehst.","en":"Please put your things in order before you leave.","ru":"Приведи, пожалуйста, свои вещи в порядок, прежде чем уйти.","vi":"Hãy thu dọn đồ đạc của bạn trước khi rời đi.","fa":"لطفا قبل از رفتن به وسایل خود نظم دهید."}]},{"word":"die Organisation","en":"organisation; organising","ru":"организация; организация (процесс)","vi":"tổ chức","fa":"سازمان","examples":[{"de":"Die Organisation der Feier war wirklich gut.","en":"The organisation of the party was really good.","ru":"Организация праздника была действительно хорошей.","vi":"Việc tổ chức lễ kỷ niệm thực sự tốt.","fa":"برگزاری جشن واقعا خوب بود."},{"de":"Sie arbeitet für eine internationale Organisation.","en":"She works for an international organisation.","ru":"Она работает в международной организации.","vi":"Cô ấy làm việc cho một tổ chức quốc tế.","fa":"او برای یک سازمان بین المللی کار می کند."},{"de":"Die Organisation hilft Menschen in Not.","en":"The organisation helps people in need.","ru":"Организация помогает нуждающимся людям.","vi":"Tổ chức giúp đỡ những người gặp khó khăn.","fa":"این سازمان به افراد نیازمند کمک می کند."}]},{"word":"organisieren","en":"to organize","ru":"организовывать","vi":"tổ chức","fa":"سازماندهی","examples":[{"de":"Wir organisieren eine Geburtstagsparty für sie.","en":"We are organizing a birthday party for her.","ru":"Мы организуем для неё вечеринку по случаю дня рождения.","vi":"Chúng tôi đang tổ chức một bữa tiệc sinh nhật cho cô ấy.","fa":"ما در حال برگزاری جشن تولد برای او هستیم."},{"de":"Er hat die ganze Reise selbst organisiert.","en":"He organized the whole trip himself.","ru":"Он сам организовал всю поездку.","vi":"Anh ấy tự tổ chức toàn bộ chuyến đi.","fa":"کل سفر را خودش سازماندهی کرد."}]},{"word":"das Original","en":"original","ru":"оригинал","vi":"bản gốc","fa":"اصلی","examples":[{"de":"Dieses Gemälde ist ein echtes Original.","en":"This painting is a real original.","ru":"Эта картина — настоящий оригинал.","vi":"Bức tranh này là một bản gốc thực sự.","fa":"این نقاشی یک اصل واقعی است."},{"de":"Bitte bringen Sie das Original des Dokuments mit.","en":"Please bring the original of the document.","ru":"Пожалуйста, принесите оригинал документа.","vi":"Vui lòng mang theo tài liệu gốc.","fa":"لطفا اصل سند را به همراه داشته باشید."}]},{"word":"der Ort","en":"place; location","ru":"место","vi":"nơi","fa":"مکان","examples":[{"de":"Das ist ein schöner Ort für ein Picknick.","en":"This is a nice place for a picnic.","ru":"Это красивое место для пикника.","vi":"Đây là một nơi tốt đẹp cho một chuyến dã ngoại.","fa":"این یک مکان خوب برای پیک نیک است."},{"de":"An welchem Ort wollen wir uns treffen?","en":"At which place do we want to meet?","ru":"В каком месте мы встретимся?","vi":"Chúng ta muốn gặp nhau ở đâu?","fa":"کجا می خواهیم ملاقات کنیم؟"}]},{"word":"die Ostsee","en":"Baltic Sea","ru":"Балтийское море","vi":"biển Baltic","fa":"دریای بالتیک","examples":[{"de":"Im Sommer fahren wir oft an die Ostsee.","en":"In summer we often go to the Baltic Sea.","ru":"Летом мы часто ездим на Балтийское море.","vi":"Vào mùa hè chúng tôi thường đến biển Baltic.","fa":"در تابستان اغلب به دریای بالتیک می رویم."},{"de":"Die Ostsee ist kühler als das Mittelmeer.","en":"The Baltic Sea is cooler than the Mediterranean.","ru":"Балтийское море прохладнее Средиземного.","vi":"Biển Baltic mát hơn Địa Trung Hải.","fa":"دریای بالتیک خنک تر از دریای مدیترانه است."},{"de":"An der Ostsee gibt es viele schöne Strände.","en":"There are many beautiful beaches on the Baltic Sea.","ru":"На Балтийском море много красивых пляжей.","vi":"Có rất nhiều bãi biển đẹp trên biển Baltic.","fa":"سواحل زیبای زیادی در دریای بالتیک وجود دارد."}]},{"word":"der Ozean","en":"ocean","ru":"океан","vi":"đại dương","fa":"اقیانوس","examples":[{"de":"Der Atlantische Ozean liegt zwischen Europa und Amerika.","en":"The Atlantic Ocean lies between Europe and America.","ru":"Атлантический океан находится между Европой и Америкой.","vi":"Đại Tây Dương nằm giữa châu Âu và châu Mỹ.","fa":"اقیانوس اطلس بین اروپا و آمریکا قرار دارد."},{"de":"Sie träumt davon, den Ozean zu überqueren.","en":"She dreams of crossing the ocean.","ru":"Она мечтает пересечь океан.","vi":"Cô mơ ước được vượt đại dương.","fa":"او رویای عبور از اقیانوس را در سر می پروراند."}]},{"word":"das Paar","en":"pair; couple","ru":"пара","vi":"cặp đôi","fa":"زوج","examples":[{"de":"Ich brauche ein neues Paar Schuhe.","en":"I need a new pair of shoes.","ru":"Мне нужна новая пара обуви.","vi":"Tôi cần một đôi giày mới.","fa":"من به یک جفت کفش نو نیاز دارم."},{"de":"Das Paar tanzt sehr elegant.","en":"The couple dances very elegantly.","ru":"Пара танцует очень элегантно.","vi":"Cặp đôi nhảy rất sang chảnh.","fa":"این زوج بسیار شیک می رقصند."}]},{"word":"das Päckchen","en":"small parcel, packet","ru":"маленькая посылка, бандероль","vi":"gói","fa":"بسته","examples":[{"de":"Ich habe meiner Oma ein Päckchen mit Schokolade geschickt.","en":"I sent my grandma a small parcel with chocolate.","ru":"Я отправил бабушке маленькую посылку с шоколадом.","vi":"Tôi gửi cho bà tôi một gói sô cô la.","fa":"برای مادربزرگم یک بسته شکلات فرستادم."},{"de":"Das Päckchen kam heute mit der Post an.","en":"The packet arrived today with the post.","ru":"Бандероль пришла сегодня по почте.","vi":"Gói hàng đã đến trong thư ngày hôm nay.","fa":"بسته امروز از طریق پست رسید."},{"de":"Auf dem Tisch liegt ein kleines Päckchen für dich.","en":"On the table there is a small parcel for you.","ru":"На столе лежит маленькая посылка для тебя.","vi":"Có một gói nhỏ dành cho bạn trên bàn.","fa":"یک بسته کوچک برای شما روی میز وجود دارد."}]},{"word":"packen","en":"to pack","ru":"паковать; упаковывать","vi":"gói","fa":"بسته","examples":[{"de":"Ich muss noch meinen Koffer packen.","en":"I still have to pack my suitcase.","ru":"Мне ещё нужно упаковать чемодан.","vi":"Tôi vẫn phải đóng gói hành lý của mình.","fa":"هنوز باید چمدانم را ببندم."},{"de":"Hast du schon deine Sachen für die Reise gepackt?","en":"Have you already packed your things for the trip?","ru":"Ты уже упаковал свои вещи для поездки?","vi":"Bạn đã chuẩn bị đồ đạc cho chuyến đi chưa?","fa":"آیا قبلاً وسایل خود را برای سفر جمع کرده اید؟"}]},{"word":"das Paket","en":"package; parcel","ru":"посылка; пакет","vi":"gói","fa":"بسته","examples":[{"de":"Heute ist ein Paket für dich angekommen.","en":"A package arrived for you today.","ru":"Сегодня для тебя пришла посылка.","vi":"Hôm nay có một gói hàng đã đến cho bạn.","fa":"امروز یک بسته برای شما رسید."},{"de":"Ich muss das Paket zur Post bringen.","en":"I have to take the package to the post office.","ru":"Мне нужно отнести посылку на почту.","vi":"Tôi phải mang gói hàng đến bưu điện.","fa":"باید بسته را به اداره پست ببرم."}]},{"word":"die Panne","en":"breakdown (mechanical); mishap","ru":"поломка; авария","vi":"sự cố","fa":"خرابی","examples":[{"de":"Unser Auto hatte auf der Autobahn eine Panne.","en":"Our car broke down on the highway.","ru":"Наша машина сломалась на автомагистрали.","vi":"Xe của chúng tôi bị hỏng trên đường cao tốc.","fa":"ماشین ما در بزرگراه خراب شد."},{"de":"Wegen einer technischen Panne fiel der Strom aus.","en":"Due to a technical malfunction, the power went out.","ru":"Из-за технической неполадки отключилось электричество.","vi":"Mất điện do trục trặc kỹ thuật.","fa":"برق به دلیل نقص فنی قطع شد."}]},{"word":"das Papier","en":"paper","ru":"бумага","vi":"tờ giấy","fa":"کاغذ","examples":[{"de":"Ich brauche ein Blatt Papier.","en":"I need a sheet of paper.","ru":"Мне нужен лист бумаги.","vi":"Tôi cần một mảnh giấy.","fa":"من به یک تکه کاغذ نیاز دارم."},{"de":"Bitte werfen Sie das Papier in den Recyclingcontainer.","en":"Please throw the paper into the recycling container.","ru":"Пожалуйста, выбросьте бумагу в контейнер для переработки.","vi":"Vui lòng vứt giấy vào thùng tái chế.","fa":"لطفا کاغذ را داخل ظرف بازیافت بیندازید."}]},{"word":"die Pappe","en":"cardboard","ru":"картон","vi":"bìa cứng","fa":"مقوا","examples":[{"de":"Die Box ist aus stabiler Pappe.","en":"The box is made of sturdy cardboard.","ru":"Коробка сделана из прочного картона.","vi":"Hộp được làm bằng bìa cứng chắc chắn.","fa":"جعبه از مقوای محکم ساخته شده است."},{"de":"Wir basteln das Schild aus Pappe.","en":"We're making the sign out of cardboard.","ru":"Мы делаем табличку из картона.","vi":"Chúng tôi làm bảng hiệu bằng bìa cứng.","fa":"علامت را از مقوا درست می کنیم."},{"de":"Alte Pappe gehört in das Altpapier.","en":"Old cardboard belongs in the paper recycling.","ru":"Старый картон нужно сдавать в макулатуру.","vi":"Các tông cũ thuộc về giấy thải.","fa":"مقوای قدیمی متعلق به کاغذهای باطله است."}]},{"word":"der Paradeiser","en":"tomato (Austrian)","ru":"помидор (австр.)","vi":"cà chua","fa":"گوجه فرنگی","examples":[{"de":"Für die Soße brauchen wir frische Paradeiser.","en":"We need fresh tomatoes for the sauce.","ru":"Для соуса нам нужны свежие помидоры.","vi":"Đối với nước sốt chúng ta cần cà chua tươi.","fa":"برای سس به گوجه فرنگی تازه نیاز داریم."},{"de":"Im Garten wachsen dieses Jahr viele Paradeiser.","en":"This year many tomatoes are growing in the garden.","ru":"В этом году в саду растёт много помидоров.","vi":"Có rất nhiều cà chua trồng trong vườn năm nay.","fa":"امسال گوجه فرنگی های زیادی در باغ می روید."}]},{"word":"parallel","en":"parallel","ru":"параллельный; параллельно","vi":"song song","fa":"موازی","examples":[{"de":"Die beiden Straßen verlaufen parallel zueinander.","en":"The two streets run parallel to each other.","ru":"Обе улицы идут параллельно друг другу.","vi":"Hai con đường chạy song song với nhau.","fa":"این دو خیابان به موازات یکدیگر قرار دارند."},{"de":"Er arbeitet parallel an zwei Projekten.","en":"He is working on two projects in parallel.","ru":"Он работает параллельно над двумя проектами.","vi":"Anh ấy đang thực hiện song song hai dự án.","fa":"او به طور موازی روی دو پروژه کار می کند."}]},{"word":"das Parfüm","en":"perfume","ru":"духи","vi":"nước hoa","fa":"عطر","examples":[{"de":"Sie trägt immer das gleiche Parfüm.","en":"She always wears the same perfume.","ru":"Она всегда носит одни и те же духи.","vi":"Cô ấy luôn xức cùng một loại nước hoa.","fa":"او همیشه از همان عطر استفاده می کند."},{"de":"Ich habe mir ein neues Parfüm gekauft.","en":"I bought myself a new perfume.","ru":"Я купила себе новые духи.","vi":"Tôi đã mua cho mình một loại nước hoa mới.","fa":"یک عطر جدید برای خودم خریدم."}]},{"word":"der Park","en":"park","ru":"парк","vi":"công viên","fa":"پارک","examples":[{"de":"Wir gehen im Park spazieren.","en":"We go for a walk in the park.","ru":"Мы гуляем в парке.","vi":"Chúng tôi đi dạo trong công viên.","fa":"میریم تو پارک قدم بزنیم."},{"de":"Die Kinder spielen im Park Fußball.","en":"The children play football in the park.","ru":"Дети играют в футбол в парке.","vi":"Bọn trẻ chơi bóng đá trong công viên.","fa":"بچه ها در پارک فوتبال بازی می کنند."}]},{"word":"parken","en":"to park","ru":"парковаться","vi":"công viên","fa":"پارک","examples":[{"de":"Hier darf man nicht parken.","en":"You are not allowed to park here.","ru":"Здесь нельзя парковаться.","vi":"Bạn không được phép đậu xe ở đây.","fa":"شما اجازه ندارید اینجا پارک کنید."},{"de":"Ich habe das Auto vor dem Haus geparkt.","en":"I parked the car in front of the house.","ru":"Я припарковал машину перед домом.","vi":"Tôi đỗ xe trước nhà.","fa":"ماشین رو جلوی خونه پارک کردم."}]},{"word":"das Parkett","en":"(dance) floor, parquet","ru":"паркет, танцевальный паркет","vi":"sàn gỗ","fa":"پارکت","examples":[{"de":"Die Paare glitten elegant über das Parkett.","en":"The couples glided elegantly across the floor.","ru":"Пары элегантно скользили по паркету.","vi":"Các cặp đôi lướt nhẹ nhàng trên sàn gỗ.","fa":"زوج ها به زیبایی روی پارکت می چرخیدند."},{"de":"Auf glattem Parkett tanzt es sich besonders leicht.","en":"It is especially easy to dance on a smooth floor.","ru":"По гладкому паркету танцевать особенно легко.","vi":"Khiêu vũ đặc biệt dễ dàng trên sàn gỗ mịn.","fa":"رقصیدن به ویژه در کف پارکت صاف آسان است."},{"de":"Sie betrat selbstbewusst das Parkett.","en":"She stepped confidently onto the dance floor.","ru":"Она уверенно вышла на паркет.","vi":"Cô tự tin bước lên sàn.","fa":"با اطمینان روی زمین رفت."}]},{"word":"parkieren","en":"to park (Swiss/Austrian)","ru":"парковаться (швейц./австр.)","vi":"công viên","fa":"پارک","examples":[{"de":"In der Innenstadt kann man das Auto schwer parkieren.","en":"It's hard to park the car in the city center.","ru":"В центре города трудно припарковать машину.","vi":"Thật khó để đỗ xe ở trung tâm thành phố.","fa":"پارک کردن ماشین در مرکز شهر سخت است."},{"de":"Bitte parkieren Sie nur auf den markierten Plätzen.","en":"Please park only in the marked spaces.","ru":"Пожалуйста, паркуйтесь только на обозначенных местах.","vi":"Vui lòng chỉ đỗ xe ở những chỗ được đánh dấu.","fa":"لطفا فقط در فضاهای مشخص شده پارک کنید."}]},{"word":"die Partei","en":"(political) party","ru":"партия","vi":"bữa tiệc","fa":"حزب","examples":[{"de":"Welche Partei hast du gewählt?","en":"Which party did you vote for?","ru":"За какую партию ты проголосовал?","vi":"Bạn đã bỏ phiếu cho đảng nào?","fa":"به کدام حزب رای دادید؟"},{"de":"Die Partei hat bei der Wahl viele Stimmen verloren.","en":"The party lost many votes in the election.","ru":"Партия потеряла много голосов на выборах.","vi":"Đảng đã mất nhiều phiếu trong cuộc bầu cử.","fa":"این حزب در انتخابات آرای زیادی را از دست داد."}]},{"word":"der Partner","en":"partner","ru":"партнёр","vi":"đối tác","fa":"شریک","examples":[{"de":"Mein Partner arbeitet in einer anderen Stadt.","en":"My partner works in a different city.","ru":"Мой партнёр работает в другом городе.","vi":"Đối tác của tôi làm việc ở một thành phố khác.","fa":"شریک زندگی من در شهر دیگری کار می کند."},{"de":"Wir suchen einen zuverlässigen Partner für das Projekt.","en":"We are looking for a reliable partner for the project.","ru":"Мы ищем надёжного партнёра для проекта.","vi":"Chúng tôi đang tìm kiếm đối tác tin cậy cho dự án.","fa":"ما به دنبال یک شریک قابل اعتماد برای پروژه هستیم."}]},{"word":"die Party","en":"party","ru":"вечеринка","vi":"bữa tiệc","fa":"حزب","examples":[{"de":"Am Samstag feiern wir eine große Party.","en":"On Saturday we're having a big party.","ru":"В субботу мы устраиваем большую вечеринку.","vi":"Chúng tôi sẽ có một bữa tiệc lớn vào thứ bảy.","fa":"ما شنبه یک جشن بزرگ داریم."},{"de":"Warst du auf der Party gestern?","en":"Were you at the party yesterday?","ru":"Ты был на вечеринке вчера?","vi":"Bạn có ở bữa tiệc ngày hôm qua không?","fa":"دیروز تو مهمونی بودی؟"}]},{"word":"der Pass","en":"passport","ru":"паспорт","vi":"hộ chiếu","fa":"پاسپورت","examples":[{"de":"Ich muss meinen Pass verlängern lassen.","en":"I need to get my passport renewed.","ru":"Мне нужно продлить паспорт.","vi":"Tôi cần gia hạn hộ chiếu của mình.","fa":"باید پاسپورتم را تمدید کنم"},{"de":"Bitte zeigen Sie mir Ihren Pass.","en":"Please show me your passport.","ru":"Пожалуйста, покажите мне ваш паспорт.","vi":"Vui lòng cho tôi xem hộ chiếu của bạn.","fa":"لطفا پاسپورت خود را به من نشان دهید."}]},{"word":"der Passagier","en":"passenger","ru":"пассажир","vi":"hành khách","fa":"مسافر","examples":[{"de":"Alle Passagiere müssen sich anschnallen.","en":"All passengers must fasten their seatbelts.","ru":"Все пассажиры должны пристегнуть ремни.","vi":"Tất cả hành khách phải thắt dây an toàn.","fa":"همه مسافران باید کمربند ایمنی خود را ببندند."},{"de":"Der Zug hatte heute nur wenige Passagiere.","en":"The train had only few passengers today.","ru":"В поезде сегодня было мало пассажиров.","vi":"Chuyến tàu hôm nay chỉ có vài hành khách.","fa":"قطار امروز فقط چند مسافر داشت."}]},{"word":"die Passagierin","en":"passenger (female)","ru":"пассажирка (женщина)","vi":"hành khách","fa":"مسافر","examples":[{"de":"Die Passagierin saß am Fenster.","en":"The (female) passenger sat by the window.","ru":"Пассажирка сидела у окна.","vi":"Người hành khách đang ngồi ở cửa sổ.","fa":"مسافر پشت پنجره نشسته بود."},{"de":"Eine Passagierin fragte den Schaffner nach dem Weg.","en":"A passenger asked the conductor for directions.","ru":"Одна пассажирка спросила у проводника дорогу.","vi":"Một hành khách hỏi người soát vé chỉ đường.","fa":"مسافری از راهبر راهنمایی خواست."},{"de":"Die Passagierin hatte zu viel Gepäck dabei.","en":"The passenger had too much luggage with her.","ru":"У пассажирки было слишком много багажа.","vi":"Hành khách mang theo quá nhiều hành lý bên mình.","fa":"مسافر چمدان زیادی با خود داشت."}]},{"word":"passen","en":"to fit; to suit","ru":"подходить; годиться","vi":"phù hợp","fa":"مناسب","examples":[{"de":"Die Hose passt mir nicht mehr.","en":"The trousers don't fit me anymore.","ru":"Брюки мне больше не подходят.","vi":"Chiếc quần không còn vừa với tôi nữa.","fa":"شلوار دیگه بهم نمیاد"},{"de":"Passt es dir, wenn wir uns am Freitag treffen?","en":"Does it suit you if we meet on Friday?","ru":"Тебе удобно, если мы встретимся в пятницу?","vi":"Sẽ ổn chứ nếu chúng ta gặp nhau vào thứ Sáu?","fa":"اگر جمعه همدیگر را ببینیم اشکالی ندارد؟"}]},{"word":"passieren","en":"to happen","ru":"случаться, происходить","vi":"xảy ra","fa":"اتفاق بیفتد","examples":[{"de":"Was ist gestern Abend passiert?","en":"What happened yesterday evening?","ru":"Что случилось вчера вечером?","vi":"Chuyện gì đã xảy ra tối qua?","fa":"دیشب چه اتفاقی افتاد؟"},{"de":"Bei dem Unfall ist zum Glück nichts Schlimmes passiert.","en":"Luckily nothing bad happened in the accident.","ru":"К счастью, во время аварии ничего плохого не произошло.","vi":"Rất may không có điều gì đáng tiếc xảy ra trong vụ tai nạn.","fa":"خوشبختانه اتفاق بدی در این تصادف رخ نداد."}]},{"word":"passiv","en":"passive","ru":"пассивный","vi":"thụ động","fa":"منفعل","examples":[{"de":"Er sitzt nur passiv da und hilft nicht mit.","en":"He just sits there passively and doesn't help.","ru":"Он просто пассивно сидит и не помогает.","vi":"Anh ta chỉ ngồi đó một cách thụ động và không giúp đỡ.","fa":"او فقط منفعلانه آنجا می نشیند و کمکی نمی کند."},{"de":"In der Diskussion war sie sehr passiv.","en":"She was very passive in the discussion.","ru":"В дискуссии она была очень пассивна.","vi":"Cô ấy rất thụ động trong cuộc thảo luận.","fa":"او در بحث بسیار منفعل بود."}]},{"word":"das Passwort","en":"a password","ru":"пароль","vi":"mật khẩu","fa":"رمز عبور","examples":[{"de":"Wähle ein sicheres Passwort, das niemand erraten kann.","en":"Choose a secure password that nobody can guess.","ru":"Выбери надёжный пароль, который никто не сможет угадать.","vi":"Chọn một mật khẩu mạnh mà không ai có thể đoán được.","fa":"یک رمز عبور قوی انتخاب کنید که هیچکس نتواند حدس بزند."},{"de":"Ich habe mein Passwort vergessen und muss es jetzt zurücksetzen.","en":"I've forgotten my password and now have to reset it.","ru":"Я забыл свой пароль и теперь должен его сбросить.","vi":"Tôi quên mật khẩu và cần đặt lại ngay bây giờ.","fa":"رمز عبور خود را فراموش کرده ام و اکنون باید آن را بازنشانی کنم."},{"de":"Bitte teile dein Passwort mit niemandem.","en":"Please don't share your password with anyone.","ru":"Пожалуйста, никому не сообщай свой пароль.","vi":"Vui lòng không chia sẻ mật khẩu của bạn với bất cứ ai.","fa":"لطفا رمز عبور خود را با کسی به اشتراک نگذارید."}]},{"word":"der Patient","en":"patient","ru":"пациент","vi":"bệnh nhân","fa":"بیمار","examples":[{"de":"Der Arzt untersucht den Patienten sehr gründlich.","en":"The doctor examines the patient very thoroughly.","ru":"Врач очень тщательно осматривает пациента.","vi":"Bác sĩ khám bệnh nhân rất cẩn thận.","fa":"پزشک بیمار را بسیار دقیق معاینه می کند."},{"de":"Im Wartezimmer sitzen viele Patienten.","en":"Many patients are sitting in the waiting room.","ru":"В приёмной сидит много пациентов.","vi":"Có rất nhiều bệnh nhân đang ngồi trong phòng chờ.","fa":"بیماران زیادی در اتاق انتظار نشسته اند."}]},{"word":"die Patientin","en":"patient (female)","ru":"пациентка (женщина)","vi":"bệnh nhân","fa":"بیمار","examples":[{"de":"Die Patientin hat starke Kopfschmerzen.","en":"The patient has a bad headache.","ru":"У пациентки сильная головная боль.","vi":"Bệnh nhân bị đau đầu dữ dội.","fa":"بیمار سردرد شدید دارد."},{"de":"Der Arzt erklärt der Patientin die Diagnose.","en":"The doctor explains the diagnosis to the patient.","ru":"Врач объясняет пациентке диагноз.","vi":"Bác sĩ giải thích chẩn đoán cho bệnh nhân.","fa":"پزشک تشخیص را به بیمار توضیح می دهد."},{"de":"Die Patientin darf morgen nach Hause gehen.","en":"The patient may go home tomorrow.","ru":"Пациентка может завтра пойти домой.","vi":"Bệnh nhân có thể về nhà vào ngày mai.","fa":"بیمار فردا می تواند به خانه برود."}]},{"word":"pauschal","en":"flat-rate; blanket (general, all-inclusive)","ru":"паушальный, общий (без учёта деталей)","vi":"tỷ giá cố định","fa":"نرخ ثابت","examples":[{"de":"Die Reise kostet pauschal 500 Euro pro Person.","en":"The trip costs a flat rate of 500 euros per person.","ru":"Поездка стоит паушально 500 евро с человека.","vi":"Chuyến đi có giá cố định là 500 euro mỗi người.","fa":"هزینه سفر برای هر نفر 500 یورو است."},{"de":"Man kann das nicht pauschal beantworten.","en":"You can't answer that in a blanket way.","ru":"На это нельзя ответить в общем виде.","vi":"Bạn không thể đưa ra một câu trả lời chung chung cho điều đó.","fa":"شما نمی توانید یک پاسخ کلی به آن بدهید."}]},{"word":"die Pauschalreise","en":"package holiday","ru":"путёвка, пакетный тур","vi":"chuyến du lịch trọn gói","fa":"تور بسته","examples":[{"de":"Wir haben eine Pauschalreise nach Mallorca gebucht.","en":"We booked a package holiday to Majorca.","ru":"Мы забронировали пакетный тур на Майорку.","vi":"Chúng tôi đã đặt một chuyến đi trọn gói đến Mallorca.","fa":"ما یک بسته سفر به مایورکا رزرو کردیم."},{"de":"Bei einer Pauschalreise sind Flug und Hotel zusammen.","en":"With a package holiday flight and hotel are together.","ru":"В пакетном туре перелёт и отель идут вместе.","vi":"Một kỳ nghỉ trọn gói bao gồm chuyến bay và khách sạn cùng nhau.","fa":"بسته تعطیلات شامل پرواز و هتل با هم است."},{"de":"Eine Pauschalreise ist oft günstiger als alles einzeln zu buchen.","en":"A package holiday is often cheaper than booking everything separately.","ru":"Пакетный тур часто дешевле, чем бронировать всё по отдельности.","vi":"Một kỳ nghỉ trọn gói thường rẻ hơn so với đặt riêng lẻ mọi thứ.","fa":"بسته تعطیلات اغلب ارزان تر از رزرو همه چیز به صورت جداگانه است."}]},{"word":"die Pause","en":"break, pause","ru":"перерыв, пауза","vi":"giờ nghỉ","fa":"استراحت","examples":[{"de":"In der Pause trinken wir einen Kaffee.","en":"During the break we drink a coffee.","ru":"На перерыве мы пьём кофе.","vi":"Chúng tôi uống cà phê trong giờ giải lao.","fa":"در زمان استراحت قهوه می نوشیم."},{"de":"Nach zwei Stunden Arbeit brauche ich eine Pause.","en":"After two hours of work I need a break.","ru":"После двух часов работы мне нужен перерыв.","vi":"Sau hai giờ làm việc, tôi cần nghỉ ngơi.","fa":"بعد از دو ساعت کار نیاز به استراحت دارم."}]},{"word":"das Pech","en":"bad luck","ru":"неудача, невезение","vi":"điều xui xẻo","fa":"بدشانسی","examples":[{"de":"So ein Pech, dass es heute regnet!","en":"What bad luck that it's raining today!","ru":"Какая неудача, что сегодня идёт дождь!","vi":"Thật xui xẻo vì hôm nay trời mưa!","fa":"آنقدر بدشانسی که امروز باران می بارد!"},{"de":"Er hatte Pech und verlor sein ganzes Geld.","en":"He had bad luck and lost all his money.","ru":"Ему не повезло, и он потерял все свои деньги.","vi":"Anh ta không may mắn và mất hết tiền.","fa":"او بدشانس بود و تمام پول خود را از دست داد."}]},{"word":"peinlich","en":"embarrassing","ru":"неловкий, постыдный","vi":"đáng xấu hổ","fa":"شرم آور","examples":[{"de":"Es war mir sehr peinlich, dass ich zu spät kam.","en":"It was very embarrassing for me that I arrived late.","ru":"Мне было очень неловко, что я опоздал.","vi":"Tôi rất xấu hổ vì đã đến muộn.","fa":"از اینکه دیر اومدم خیلی خجالت کشیدم."},{"de":"Das war eine peinliche Situation für alle.","en":"That was an embarrassing situation for everyone.","ru":"Это была неловкая ситуация для всех.","vi":"Đây là một tình huống đáng xấu hổ cho tất cả mọi người.","fa":"این وضعیت برای همه شرم آور بود."}]},{"word":"das Pendel","en":"pendulum","ru":"маятник","vi":"con lắc","fa":"آونگ","examples":[{"de":"Das Pendel schwingt gleichmäßig hin und her.","en":"The pendulum swings back and forth evenly.","ru":"Маятник равномерно качается туда-сюда.","vi":"Con lắc dao động qua lại đều nhau.","fa":"آونگ به طور مساوی به جلو و عقب می چرخد."},{"de":"Die Länge des Pendels bestimmt die Dauer einer Schwingung.","en":"The length of the pendulum determines the period of one oscillation.","ru":"Длина маятника определяет период одного колебания.","vi":"Chiều dài của con lắc quyết định thời gian dao động.","fa":"طول آونگ مدت یک نوسان را تعیین می کند."},{"de":"Eine alte Uhr wird von einem Pendel angetrieben.","en":"An old clock is driven by a pendulum.","ru":"Старые часы приводятся в движение маятником.","vi":"Một chiếc đồng hồ cũ được cung cấp năng lượng bởi một con lắc.","fa":"یک ساعت قدیمی با یک آونگ کار می کند."}]},{"word":"die Pension","en":"guesthouse; pension (retirement)","ru":"пансион; пенсия","vi":"nhà khách","fa":"مهمانخانه","examples":[{"de":"Wir übernachten in einer kleinen Pension am See.","en":"We are staying overnight in a small guesthouse by the lake.","ru":"Мы ночуем в маленьком пансионе у озера.","vi":"Chúng tôi qua đêm tại một nhà khách nhỏ bên hồ.","fa":"شب را در مهمانخانه کوچکی در کنار دریاچه می گذرانیم."},{"de":"Nach vierzig Arbeitsjahren bekommt sie eine gute Pension.","en":"After forty years of work she gets a good pension.","ru":"После сорока лет работы она получает хорошую пенсию.","vi":"Sau bốn mươi năm làm việc, cô nhận được một khoản lương hưu khá tốt.","fa":"بعد از چهل سال کار حقوق بازنشستگی خوبی می گیرد."}]},{"word":"pensionieren","en":"to retire, to pension off","ru":"выходить на пенсию, отправлять на пенсию","vi":"nghỉ hưu","fa":"بازنشسته شدن","examples":[{"de":"Mein Vater lässt sich nächstes Jahr pensionieren.","en":"My father is retiring next year.","ru":"Мой отец выходит на пенсию в следующем году.","vi":"Bố tôi sẽ nghỉ hưu vào năm tới.","fa":"پدرم سال آینده بازنشسته می شود."},{"de":"Sie wurde mit 63 pensioniert.","en":"She was pensioned off at 63.","ru":"Её отправили на пенсию в 63 года.","vi":"Bà nghỉ hưu ở tuổi 63.","fa":"او در 63 سالگی بازنشسته شد."},{"de":"Viele Lehrer werden früh pensioniert.","en":"Many teachers are retired early.","ru":"Многих учителей отправляют на пенсию досрочно.","vi":"Nhiều giáo viên nghỉ hưu sớm.","fa":"بسیاری از معلمان پیش از موعد بازنشسته می شوند."}]},{"word":"der Pensionist","en":"pensioner, retiree","ru":"пенсионер","vi":"người về hưu","fa":"مستمری بگیر","examples":[{"de":"Viele Pensionisten machen morgens einen Spaziergang im Park.","en":"Many pensioners take a walk in the park in the morning.","ru":"Многие пенсионеры утром гуляют в парке.","vi":"Nhiều người về hưu đi dạo buổi sáng trong công viên.","fa":"بسیاری از بازنشستگان صبحگاهی در پارک قدم می زنند."},{"de":"Als Pensionist hat er endlich Zeit für sein Hobby.","en":"As a pensioner he finally has time for his hobby.","ru":"Как пенсионер, он наконец нашёл время для своего хобби.","vi":"Là một người hưu trí, cuối cùng anh cũng có thời gian cho sở thích của mình.","fa":"او به عنوان یک مستمری بگیر بالاخره برای سرگرمی خود وقت دارد."}]},{"word":"die Pensionistin","en":"pensioner, retiree (female, Austrian)","ru":"пенсионерка (женщина, австрийский вариант немецкого)","vi":"người về hưu","fa":"مستمری بگیر","examples":[{"de":"Die Pensionistin kümmert sich gern um ihre Enkel.","en":"The pensioner enjoys looking after her grandchildren.","ru":"Пенсионерка с удовольствием присматривает за внуками.","vi":"Người hưu trí thích chăm sóc cháu của mình.","fa":"بازنشسته از مراقبت از نوه هایش لذت می برد."},{"de":"Als Pensionistin hat sie endlich Zeit zum Malen.","en":"As a pensioner she finally has time to paint.","ru":"Как пенсионерка, она наконец-то может рисовать.","vi":"Là một người hưu trí, cuối cùng cô cũng có thời gian để vẽ.","fa":"او به عنوان یک مستمری بگیر بالاخره وقت نقاشی کردن دارد."},{"de":"Die Pensionistin geht jeden Morgen spazieren.","en":"The pensioner goes for a walk every morning.","ru":"Пенсионерка каждое утро выходит на прогулку.","vi":"Người hưu trí đi dạo vào mỗi buổi sáng.","fa":"مستمری بگیر هر روز صبح به پیاده روی می رود."}]},{"word":"per","en":"by, via","ru":"посредством, через","vi":"mỗi","fa":"در هر","examples":[{"de":"Ich schicke dir die Fotos per E-Mail.","en":"I'll send you the photos by email.","ru":"Я пришлю тебе фотографии по электронной почте.","vi":"Tôi sẽ gửi cho bạn những bức ảnh qua email.","fa":"عکس ها رو برات ایمیل میکنم"},{"de":"Die Ware wird per Post geliefert.","en":"The goods are delivered by mail.","ru":"Товар доставляется по почте.","vi":"Hàng được giao qua đường bưu điện.","fa":"کالا از طریق پست تحویل داده می شود."}]},{"word":"perfekt","en":"perfect","ru":"идеальный, совершенный","vi":"hoàn hảo","fa":"کامل","examples":[{"de":"Ihre Präsentation war einfach perfekt.","en":"Her presentation was simply perfect.","ru":"Её презентация была просто идеальной.","vi":"Bài thuyết trình của bạn thật hoàn hảo.","fa":"ارائه شما فقط عالی بود."},{"de":"Niemand ist perfekt.","en":"Nobody is perfect.","ru":"Никто не идеален.","vi":"Không ai là hoàn hảo.","fa":"هیچکس کامل نیست"}]},{"word":"der Perfektionist","en":"perfectionist (male)","ru":"перфекционист (мужчина)","vi":"người cầu toàn","fa":"کمال گرا","examples":[{"de":"Mein Chef ist ein echter Perfektionist.","en":"My boss is a real perfectionist.","ru":"Мой начальник — настоящий перфекционист.","vi":"Sếp của tôi thực sự là một người cầu toàn.","fa":"رئیس من یک کمال گرا واقعی است."},{"de":"Als Perfektionist gibt er sich nie mit weniger zufrieden.","en":"As a perfectionist he is never satisfied with less.","ru":"Как перфекционист, он никогда не довольствуется меньшим.","vi":"Là người theo chủ nghĩa hoàn hảo, anh ấy không bao giờ chấp nhận ít hơn.","fa":"او به عنوان یک کمال گرا هرگز به کمتر راضی نمی شود."},{"de":"Ein Perfektionist überprüft jedes Detail mehrmals.","en":"A perfectionist checks every detail several times.","ru":"Перфекционист по нескольку раз проверяет каждую деталь.","vi":"Người cầu toàn kiểm tra từng chi tiết nhiều lần.","fa":"یک کمال گرا همه جزئیات را چندین بار بررسی می کند."}]},{"word":"die Perlenkette","en":"pearl necklace","ru":"жемчужное ожерелье, нитка жемчуга","vi":"vòng cổ ngọc trai","fa":"گردنبند مروارید","examples":[{"de":"Zur Feier trägt sie eine schöne Perlenkette.","en":"For the celebration she is wearing a beautiful pearl necklace.","ru":"На торжество она надевает красивое жемчужное ожерелье.","vi":"Để ăn mừng, cô đeo một chiếc vòng cổ ngọc trai tuyệt đẹp.","fa":"برای جشن او یک گردنبند مروارید زیبا می‌بندد."},{"de":"Die Perlenkette war ein Geschenk ihrer Großmutter.","en":"The pearl necklace was a gift from her grandmother.","ru":"Жемчужное ожерелье было подарком её бабушки.","vi":"Chiếc vòng cổ ngọc trai là món quà của bà cô.","fa":"گردنبند مروارید هدیه مادربزرگش بود."},{"de":"Die Perlenkette passt perfekt zu dem schwarzen Kleid.","en":"The pearl necklace goes perfectly with the black dress.","ru":"Жемчужное ожерелье прекрасно подходит к чёрному платью.","vi":"Vòng cổ ngọc trai kết hợp hoàn hảo với chiếc váy đen.","fa":"گردنبند مروارید کاملاً با لباس مشکی ست می شود."}]},{"word":"der Perron","en":"platform (railway)","ru":"платформа, перрон","vi":"nền tảng","fa":"پلت فرم","examples":[{"de":"Der Zug fährt auf Perron 3 ab.","en":"The train departs from platform 3.","ru":"Поезд отправляется с платформы 3.","vi":"Tàu khởi hành ở sân ga số 3.","fa":"قطار روی سکوی 3 حرکت می کند."},{"de":"Wir warten auf dem Perron auf unseren Zug.","en":"We are waiting on the platform for our train.","ru":"Мы ждём наш поезд на платформе.","vi":"Chúng tôi đợi chuyến tàu của mình trên sân ga.","fa":"روی سکو منتظر قطارمان هستیم."}]},{"word":"die Person","en":"person","ru":"человек, лицо","vi":"người đó","fa":"شخص","examples":[{"de":"An dem Tisch sitzen vier Personen.","en":"Four people are sitting at the table.","ru":"За столом сидят четыре человека.","vi":"Bốn người đang ngồi ở bàn.","fa":"چهار نفر پشت میز نشسته اند."},{"de":"Sie ist eine sehr freundliche Person.","en":"She is a very friendly person.","ru":"Она очень дружелюбный человек.","vi":"Cô ấy là một người rất thân thiện.","fa":"او فردی بسیار صمیمی است."}]},{"word":"das Personal","en":"staff, personnel","ru":"персонал","vi":"nhân viên","fa":"کارکنان","examples":[{"de":"Das Hotel sucht neues Personal für die Küche.","en":"The hotel is looking for new staff for the kitchen.","ru":"Отель ищет новый персонал для кухни.","vi":"Khách sạn đang tìm kiếm nhân viên mới cho nhà bếp.","fa":"هتل به دنبال کارکنان جدید برای آشپزخانه می باشد."},{"de":"Das Personal ist sehr freundlich und hilfsbereit.","en":"The staff is very friendly and helpful.","ru":"Персонал очень дружелюбный и готов помочь.","vi":"Các nhân viên rất thân thiện và hữu ích.","fa":"کارکنان بسیار دوستانه و مفید هستند."}]},{"word":"der Personalausweis","en":"an identity card (national ID)","ru":"удостоверение личности (паспорт-карта)","vi":"chứng minh nhân dân","fa":"the identity card","examples":[{"de":"Für die Reise brauchen wir unseren Personalausweis.","en":"For the trip we need our identity card.","ru":"Для поездки нам нужно удостоверение личности.","vi":"Chúng tôi cần chứng minh nhân dân cho chuyến đi.","fa":"برای سفر به شناسنامه نیاز داریم."},{"de":"An der Grenze musste ich meinen Personalausweis zeigen.","en":"At the border I had to show my identity card.","ru":"На границе мне пришлось предъявить удостоверение личности.","vi":"Đến cửa khẩu tôi phải xuất trình CMND.","fa":"در مرز باید شناسنامه ام را نشان می دادم."},{"de":"Mein Personalausweis ist nächsten Monat nicht mehr gültig.","en":"My identity card will no longer be valid next month.","ru":"В следующем месяце моё удостоверение личности станет недействительным.","vi":"Thẻ ID của tôi sẽ không còn hiệu lực vào tháng tới.","fa":"کارت شناسایی من از ماه آینده دیگر معتبر نخواهد بود."}]},{"word":"die Personalie","en":"personal detail; personnel matter","ru":"анкетные данные; кадровый вопрос","vi":"nhân sự","fa":"پرسنل","examples":[{"de":"Bitte geben Sie zuerst Ihre Personalien an.","en":"Please give your personal details first.","ru":"Сначала сообщите, пожалуйста, ваши анкетные данные.","vi":"Vui lòng cung cấp thông tin cá nhân của bạn trước.","fa":"لطفا ابتدا مشخصات شخصی خود را ارائه دهید."},{"de":"Die Polizei nahm die Personalien der Zeugen auf.","en":"The police took down the personal details of the witnesses.","ru":"Полиция записала анкетные данные свидетелей.","vi":"Cảnh sát đã ghi lại thông tin cá nhân của các nhân chứng.","fa":"پلیس اطلاعات شخصی شاهدان را ثبت کرد."},{"de":"Diese Personalie wird in der nächsten Sitzung besprochen.","en":"This personnel matter will be discussed in the next meeting.","ru":"Этот кадровый вопрос обсудят на следующем совещании.","vi":"Nhân sự này sẽ được thảo luận tại cuộc họp tiếp theo.","fa":"این پرسنل در جلسه بعدی مورد بحث قرار خواهند گرفت."}]},{"word":"der Personenschaden","en":"personal injury; injury to persons","ru":"телесные повреждения, ущерб здоровью (о людях)","vi":"thương tích cá nhân","fa":"آسیب شخصی","examples":[{"de":"Bei dem Unfall gab es nur Sachschaden, keinen Personenschaden.","en":"In the accident there was only property damage, no personal injury.","ru":"В аварии был только материальный ущерб, без пострадавших.","vi":"Vụ tai nạn chỉ gây thiệt hại về tài sản và không có thương tích về người.","fa":"این حادثه فقط خسارت مالی و جانی به همراه داشت."},{"de":"Wegen eines Personenschadens hat der Zug Verspätung.","en":"The train is delayed due to a personal injury.","ru":"Поезд задерживается из-за несчастного случая с человеком.","vi":"Chuyến tàu bị trì hoãn do thương tích cá nhân.","fa":"قطار به دلیل جراحت شخصی تاخیر دارد."},{"de":"Zum Glück kam es zu keinem Personenschaden.","en":"Fortunately no one was injured.","ru":"К счастью, никто не пострадал.","vi":"May mắn thay không có thương tích.","fa":"خوشبختانه مصدومی نداشت."}]},{"word":"der Personenstand","en":"marital/civil status","ru":"семейное (гражданское) состояние","vi":"tình trạng dân sự","fa":"وضعیت مدنی","examples":[{"de":"Bitte geben Sie im Formular Ihren Personenstand an.","en":"Please state your marital status on the form.","ru":"Пожалуйста, укажите в анкете ваше семейное положение.","vi":"Vui lòng cho biết hộ tịch của bạn trong mẫu đơn.","fa":"لطفا وضعیت مدنی خود را در فرم ذکر کنید."},{"de":"Ihr Personenstand hat sich nach der Heirat geändert.","en":"Her civil status changed after the wedding.","ru":"Её гражданское состояние изменилось после свадьбы.","vi":"Hộ tịch của bạn đã thay đổi sau khi kết hôn.","fa":"وضعیت مدنی شما بعد از ازدواج تغییر کرد."}]},{"word":"persönlich","en":"personal, in person","ru":"личный, лично","vi":"cá nhân","fa":"شخصی","examples":[{"de":"Ich möchte persönlich mit dir sprechen.","en":"I'd like to speak with you in person.","ru":"Я хотел бы поговорить с вами лично.","vi":"Tôi muốn nói chuyện riêng với bạn.","fa":"من می خواهم شخصاً با شما صحبت کنم."},{"de":"Das ist meine persönliche Meinung.","en":"That's my personal opinion.","ru":"Это моё личное мнение.","vi":"Đây là ý kiến ​​​​cá nhân của tôi.","fa":"این نظر شخصی من است."},{"de":"Nimm es nicht persönlich.","en":"Don't take it personally.","ru":"Не принимай это на свой счёт.","vi":"Đừng coi đó là chuyện cá nhân.","fa":"آن را شخصی نگیرید."}]},{"word":"die Pfanne","en":"frying pan","ru":"сковорода","vi":"cái chảo","fa":"تابه","examples":[{"de":"Ich brate das Ei in der Pfanne.","en":"I fry the egg in the pan.","ru":"Я жарю яйцо на сковороде.","vi":"Tôi chiên trứng trong chảo.","fa":"تخم مرغ را در تابه سرخ می کنم."},{"de":"Die Pfanne ist noch heiß, pass auf!","en":"The pan is still hot, be careful!","ru":"Сковорода ещё горячая, будь осторожен!","vi":"Chảo vẫn còn nóng, hãy cẩn thận!","fa":"تابه هنوز داغ است، مراقب باشید!"}]},{"word":"der Pfeffer","en":"pepper","ru":"перец","vi":"hạt tiêu","fa":"فلفل","examples":[{"de":"Gib etwas Salz und Pfeffer an die Suppe.","en":"Add some salt and pepper to the soup.","ru":"Добавь немного соли и перца в суп.","vi":"Thêm một ít muối và hạt tiêu vào súp.","fa":"مقداری نمک و فلفل به سوپ اضافه کنید."},{"de":"Der Pfeffer steht neben dem Salz auf dem Tisch.","en":"The pepper is next to the salt on the table.","ru":"Перец стоит на столе рядом с солью.","vi":"Hạt tiêu ở trên bàn cạnh muối.","fa":"فلفل روی میز کنار نمک است."}]},{"word":"pflanzen","en":"to plant","ru":"сажать (растения)","vi":"thực vật","fa":"گیاهان","examples":[{"de":"Im Frühling pflanzen wir Blumen im Garten.","en":"In spring we plant flowers in the garden.","ru":"Весной мы сажаем цветы в саду.","vi":"Vào mùa xuân, chúng tôi trồng hoa trong vườn.","fa":"در بهار در باغ گل می کاریم."},{"de":"Mein Opa hat diesen Baum vor fünfzig Jahren gepflanzt.","en":"My grandpa planted this tree fifty years ago.","ru":"Мой дедушка посадил это дерево пятьдесят лет назад.","vi":"Ông tôi đã trồng cây này cách đây năm mươi năm.","fa":"پدربزرگ من پنجاه سال پیش این درخت را کاشت."}]},{"word":"das Pflaster","en":"plaster, adhesive bandage","ru":"пластырь","vi":"vỉa hè","fa":"پیاده رو","examples":[{"de":"Ich klebe ein Pflaster auf die kleine Wunde.","en":"I put a plaster on the small wound.","ru":"Я наклеиваю пластырь на маленькую рану.","vi":"Tôi dán một miếng thạch cao lên vết thương nhỏ.","fa":"روی زخم کوچک گچ گذاشتم."},{"de":"Hast du ein Pflaster für meinen Finger?","en":"Do you have a plaster for my finger?","ru":"У тебя есть пластырь для моего пальца?","vi":"Bạn có miếng dán cho ngón tay của tôi không?","fa":"برای انگشت من گچ داری؟"}]},{"word":"die Pflaume","en":"plum","ru":"слива","vi":"quả mận","fa":"آلو","examples":[{"de":"Im Garten wachsen süße Pflaumen.","en":"Sweet plums grow in the garden.","ru":"В саду растут сладкие сливы.","vi":"Mận ngọt mọc trong vườn.","fa":"آلوهای شیرین در باغ می رویند."},{"de":"Sie backt einen Kuchen mit Pflaumen.","en":"She is baking a cake with plums.","ru":"Она печёт пирог со сливами.","vi":"Cô ấy nướng một chiếc bánh với mận.","fa":"او یک کیک با آلو می پزد."}]},{"word":"pflegen","en":"to take care of, to nurse","ru":"ухаживать, заботиться","vi":"duy trì","fa":"حفظ کند","examples":[{"de":"Sie pflegt ihre kranke Mutter zu Hause.","en":"She takes care of her sick mother at home.","ru":"Она ухаживает за своей больной матерью дома.","vi":"Cô ấy chăm sóc mẹ ốm ở nhà.","fa":"او در خانه از مادر بیمارش مراقبت می کند."},{"de":"Man muss die Pflanzen regelmäßig pflegen.","en":"You have to take care of the plants regularly.","ru":"За растениями нужно регулярно ухаживать.","vi":"Bạn phải chăm sóc cây thường xuyên.","fa":"شما باید به طور منظم از گیاهان مراقبت کنید."}]},{"word":"der Pfleger","en":"carer, nurse (male)","ru":"санитар, сиделка, медбрат (мужчина)","vi":"y tá","fa":"پرستار","examples":[{"de":"Der Pfleger hilft den Patienten beim Aufstehen.","en":"The carer helps the patients get up.","ru":"Санитар помогает пациентам встать.","vi":"Y tá đỡ bệnh nhân đứng dậy.","fa":"پرستار به بیمار کمک می کند تا بلند شود."},{"de":"Mein Bruder arbeitet als Pfleger im Krankenhaus.","en":"My brother works as a nurse in the hospital.","ru":"Мой брат работает медбратом в больнице.","vi":"Anh trai tôi làm y tá ở bệnh viện.","fa":"برادرم به عنوان پرستار در بیمارستان کار می کند."},{"de":"Der Pfleger ist immer freundlich und geduldig.","en":"The carer is always friendly and patient.","ru":"Санитар всегда приветлив и терпелив.","vi":"Y tá luôn thân thiện và kiên nhẫn.","fa":"پرستار همیشه صبور و صبور است."}]},{"word":"die Pflegerin","en":"carer, nurse (female)","ru":"санитарка, сиделка, медсестра (женщина)","vi":"y tá","fa":"پرستار","examples":[{"de":"Die Pflegerin kümmert sich liebevoll um die Senioren.","en":"The carer looks after the seniors lovingly.","ru":"Сиделка заботливо ухаживает за пожилыми людьми.","vi":"Cô y tá tận tình chăm sóc các cụ già.","fa":"پرستار با محبت از سالمندان مراقبت می کند."},{"de":"Eine Pflegerin kommt jeden Tag zu meiner Großmutter.","en":"A carer comes to my grandmother every day.","ru":"К моей бабушке каждый день приходит сиделка.","vi":"Một y tá đến gặp bà tôi mỗi ngày.","fa":"هر روز یک پرستار پیش مادربزرگم می آید."},{"de":"Die Pflegerin notiert die Werte des Patienten.","en":"The nurse notes down the patient's readings.","ru":"Медсестра записывает показатели пациента.","vi":"Y tá ghi nhận những giá trị của bệnh nhân.","fa":"پرستار ارزش های بیمار را یادداشت می کند."}]},{"word":"die Pflicht","en":"duty, obligation","ru":"долг, обязанность","vi":"nhiệm vụ","fa":"وظیفه","examples":[{"de":"Es ist meine Pflicht, dir zu helfen.","en":"It is my duty to help you.","ru":"Это мой долг — помочь тебе.","vi":"Nhiệm vụ của tôi là giúp đỡ bạn.","fa":"این وظیفه من است که به شما کمک کنم."},{"de":"Pünktlichkeit gehört zu seinen Pflichten als Angestellter.","en":"Punctuality is one of his duties as an employee.","ru":"Пунктуальность — одна из его обязанностей как сотрудника.","vi":"Đúng giờ là một trong những nhiệm vụ của anh ấy với tư cách là một nhân viên.","fa":"وقت شناسی یکی از وظایف او به عنوان یک کارمند است."}]},{"word":"die Phantasie","en":"imagination, fantasy","ru":"воображение, фантазия","vi":"trí tưởng tượng","fa":"تخیل","examples":[{"de":"Kinder haben oft eine lebhafte Phantasie.","en":"Children often have a vivid imagination.","ru":"У детей часто богатое воображение.","vi":"Trẻ em thường có trí tưởng tượng sống động.","fa":"کودکان اغلب تخیل روشنی دارند."},{"de":"Mit ein bisschen Phantasie kannst du aus alten Sachen etwas Schönes machen.","en":"With a bit of imagination you can make something nice out of old things.","ru":"С небольшой фантазией из старых вещей можно сделать что-то красивое.","vi":"Với một chút trí tưởng tượng, bạn có thể biến những thứ cũ thành một thứ gì đó đẹp đẽ.","fa":"با کمی تخیل می توانید چیزهای قدیمی را به چیزی زیبا تبدیل کنید."},{"de":"Seine Geschichte war reine Phantasie.","en":"His story was pure fantasy.","ru":"Его история была чистой фантазией.","vi":"Câu chuyện của anh ấy hoàn toàn là tưởng tượng.","fa":"داستان او فانتزی محض بود."}]},{"word":"die Philosophie","en":"philosophy","ru":"философия","vi":"triết lý","fa":"فلسفه","examples":[{"de":"Die griechische Philosophie prägt das westliche Denken bis heute.","en":"Greek philosophy still shapes Western thought today.","ru":"Греческая философия и сегодня определяет западное мышление.","vi":"Triết học Hy Lạp tiếp tục định hình tư tưởng phương Tây ngày nay.","fa":"فلسفه یونان همچنان به شکل دادن به تفکر غربی امروز ادامه می دهد."},{"de":"Er interessiert sich seit seiner Jugend für Philosophie.","en":"He has been interested in philosophy since his youth.","ru":"Он интересуется философией с юности.","vi":"Ông quan tâm đến triết học từ khi còn trẻ.","fa":"او از دوران جوانی به فلسفه علاقه داشت."},{"de":"In der Vorlesung sprechen wir über die Philosophie der Aufklärung.","en":"In the lecture we talk about the philosophy of the Enlightenment.","ru":"На лекции мы говорим о философии эпохи Просвещения.","vi":"Trong bài giảng chúng ta nói về triết lý Khai sáng.","fa":"در سخنرانی در مورد فلسفه روشنگری صحبت می کنیم."}]},{"word":"der Photograph","en":"photographer","ru":"фотограф","vi":"nhiếp ảnh gia","fa":"عکاس","examples":[{"de":"Der Photograph machte schöne Bilder von der Hochzeit.","en":"The photographer took lovely pictures of the wedding.","ru":"Фотограф сделал прекрасные снимки со свадьбы.","vi":"Nhiếp ảnh gia đã chụp được những bức ảnh đẹp trong đám cưới.","fa":"عکاس عکس های زیبایی از مراسم عروسی گرفت."},{"de":"Mein Bruder ist Photograph von Beruf.","en":"My brother is a photographer by profession.","ru":"Мой брат фотограф по профессии.","vi":"Anh trai tôi là một nhiếp ảnh gia chuyên nghiệp.","fa":"برادر من حرفه ای عکاس است."},{"de":"Wir haben einen Photographen für das Fest engagiert.","en":"We hired a photographer for the party.","ru":"Мы наняли фотографа на праздник.","vi":"Chúng tôi đã thuê một nhiếp ảnh gia cho lễ hội.","fa":"ما یک عکاس برای جشنواره استخدام کردیم."}]},{"word":"die Photographie","en":"photograph; photography","ru":"фотография; фотография (искусство)","vi":"nhiếp ảnh","fa":"عکاسی","examples":[{"de":"An der Wand hängt eine alte Photographie meiner Großeltern.","en":"On the wall hangs an old photograph of my grandparents.","ru":"На стене висит старая фотография моих бабушки и дедушки.","vi":"Có một bức ảnh cũ của ông bà tôi treo trên tường.","fa":"یک عکس قدیمی از پدربزرگ و مادربزرگم به دیوار آویزان است."},{"de":"Sie interessiert sich für Photographie und besucht einen Kurs.","en":"She is interested in photography and is taking a course.","ru":"Она интересуется фотографией и ходит на курс.","vi":"Cô ấy quan tâm đến nhiếp ảnh và đang tham gia một khóa học.","fa":"او به عکاسی علاقه دارد و در حال گذراندن دوره است."},{"de":"Diese Photographie wurde vor hundert Jahren aufgenommen.","en":"This photograph was taken a hundred years ago.","ru":"Эта фотография была сделана сто лет назад.","vi":"Bức ảnh này được chụp cách đây một trăm năm.","fa":"این عکس صد سال پیش گرفته شده است."}]},{"word":"das Picknick","en":"picnic","ru":"пикник","vi":"buổi dã ngoại","fa":"پیک نیک","examples":[{"de":"Am Sonntag machen wir ein Picknick im Park.","en":"On Sunday we're having a picnic in the park.","ru":"В воскресенье мы устраиваем пикник в парке.","vi":"Vào chủ nhật chúng tôi đi dã ngoại ở công viên.","fa":"یکشنبه یک پیک نیک در پارک داریم."},{"de":"Für das Picknick packen wir Brot, Käse und Obst ein.","en":"For the picnic we pack bread, cheese and fruit.","ru":"Для пикника мы берём хлеб, сыр и фрукты.","vi":"Chúng tôi gói bánh mì, phô mai và trái cây cho chuyến dã ngoại.","fa":"نان، پنیر و میوه را برای پیک نیک بسته بندی می کنیم."}]},{"word":"die Pille","en":"pill","ru":"таблетка","vi":"viên thuốc","fa":"قرص","examples":[{"de":"Der Arzt verschrieb mir eine Pille gegen die Schmerzen.","en":"The doctor prescribed me a pill for the pain.","ru":"Врач прописал мне таблетку от боли.","vi":"Bác sĩ kê cho tôi một viên thuốc giảm đau.","fa":"دکتر برای من یک قرص برای درد تجویز کرد."},{"de":"Nimm die Pille bitte nach dem Essen ein.","en":"Please take the pill after the meal.","ru":"Принимайте таблетку, пожалуйста, после еды.","vi":"Hãy uống thuốc sau khi ăn.","fa":"لطفا قرص را بعد از غذا بخورید."},{"de":"Sie muss jeden Morgen eine Pille schlucken.","en":"She has to swallow a pill every morning.","ru":"Ей каждое утро нужно глотать таблетку.","vi":"Cô ấy phải nuốt một viên thuốc vào mỗi buổi sáng.","fa":"او باید هر روز صبح یک قرص ببلعد."}]},{"word":"der Pilot","en":"pilot","ru":"пилот, лётчик","vi":"phi công","fa":"خلبان","examples":[{"de":"Daniel wird später Pilot.","en":"Daniel is going to become a pilot.","ru":"Даниэль станет пилотом.","vi":"Daniel sau đó trở thành phi công.","fa":"دانیل بعداً خلبان می شود."},{"de":"Der Pilot begrüßte die Passagiere an Bord.","en":"The pilot welcomed the passengers on board.","ru":"Пилот поприветствовал пассажиров на борту.","vi":"Phi công chào đón hành khách lên máy bay.","fa":"خلبان از مسافران در هواپیما استقبال کرد."},{"de":"Mein Onkel ist seit zwanzig Jahren Pilot.","en":"My uncle has been a pilot for twenty years.","ru":"Мой дядя работает пилотом уже двадцать лет.","vi":"Chú tôi đã làm phi công được hai mươi năm.","fa":"عموی من بیست سال است که خلبان است."}]},{"word":"der Pilz","en":"mushroom","ru":"гриб","vi":"nấm","fa":"قارچ","examples":[{"de":"Im Wald haben wir viele Pilze gefunden.","en":"We found many mushrooms in the forest.","ru":"В лесу мы нашли много грибов.","vi":"Chúng tôi tìm thấy rất nhiều nấm trong rừng.","fa":"ما قارچ های زیادی در جنگل پیدا کردیم."},{"de":"Man sollte nur Pilze essen, die man kennt.","en":"You should only eat mushrooms that you know.","ru":"Есть следует только те грибы, которые знаешь.","vi":"Bạn chỉ nên ăn nấm mà bạn biết.","fa":"فقط باید قارچ هایی بخورید که می شناسید."}]},{"word":"die Pinnwand","en":"a wall or pinboard where posts appear","ru":"стена, доска для сообщений (где появляются посты)","vi":"bảng ghim","fa":"the pinboard","examples":[{"de":"Nutzer haben normalerweise viele Posts auf ihrer Pinnwand.","en":"Users normally have lots of posts on their wall.","ru":"У пользователей обычно много постов на стене.","vi":"Người dùng thường có rất nhiều bài viết trên tường của họ.","fa":"کاربران معمولاً تعداد زیادی پست روی دیوار خود دارند."},{"de":"Auf seiner Pinnwand findet man nur Fotos von seinem Hund.","en":"On his wall you'll find only photos of his dog.","ru":"На его стене найдёшь только фотографии его собаки.","vi":"Trên tường của anh ấy, bạn chỉ có thể tìm thấy hình ảnh con chó của anh ấy.","fa":"روی دیوار او فقط می توانید عکس های سگش را پیدا کنید."},{"de":"Freunde können Nachrichten auf deiner Pinnwand hinterlassen.","en":"Friends can leave messages on your wall.","ru":"Друзья могут оставлять сообщения на твоей стене.","vi":"Bạn bè có thể để lại tin nhắn trên tường của bạn.","fa":"دوستان می توانند روی دیوار شما پیام بگذارند."}]},{"word":"die Pirouette","en":"pirouette","ru":"пируэт","vi":"trò cướp biển","fa":"پیروت","examples":[{"de":"Die Ballerina drehte eine perfekte Pirouette.","en":"The ballerina performed a perfect pirouette.","ru":"Балерина выполнила безупречный пируэт.","vi":"Nữ diễn viên ballet đã thực hiện một màn xoay tròn hoàn hảo.","fa":"بالرین یک پیروت عالی انجام داد."},{"de":"Eine saubere Pirouette erfordert viel Gleichgewicht.","en":"A clean pirouette requires a lot of balance.","ru":"Чистый пируэт требует хорошего равновесия.","vi":"Một chiếc pirouette sạch sẽ đòi hỏi rất nhiều sự cân bằng.","fa":"یک پیروت تمیز به تعادل زیادی نیاز دارد."},{"de":"Er übte die Pirouette so lange, bis sie gelang.","en":"He practised the pirouette until he got it right.","ru":"Он отрабатывал пируэт, пока не получилось.","vi":"Anh ấy đã tập múa pirouette cho đến khi thành công.","fa":"او پیروت را تمرین کرد تا اینکه موفق شد."}]},{"word":"die Pizza","en":"pizza","ru":"пицца","vi":"bánh pizza","fa":"پیتزا","examples":[{"de":"Wir bestellen heute Abend eine Pizza.","en":"We are ordering a pizza tonight.","ru":"Сегодня вечером мы заказываем пиццу.","vi":"Chúng tôi sẽ đặt pizza tối nay.","fa":"ما امشب پیتزا سفارش می دهیم."},{"de":"Die Pizza mit Käse und Tomaten schmeckt mir am besten.","en":"I like the pizza with cheese and tomatoes best.","ru":"Мне больше всего нравится пицца с сыром и помидорами.","vi":"Tôi thích pizza với phô mai và cà chua nhất.","fa":"من پیتزا را با پنیر و گوجه فرنگی بیشتر دوست دارم."}]},{"word":"das Plakat","en":"poster","ru":"плакат, афиша","vi":"áp phích","fa":"پوستر","examples":[{"de":"An der Wand hängt ein großes Plakat vom Konzert.","en":"A big concert poster hangs on the wall.","ru":"На стене висит большой плакат с концерта.","vi":"Có một tấm áp phích lớn về buổi hòa nhạc treo trên tường.","fa":"یک پوستر بزرگ از کنسرت روی دیوار آویزان شده است."},{"de":"Wir haben Plakate für unser Schulfest gemacht.","en":"We made posters for our school festival.","ru":"Мы сделали плакаты для нашего школьного праздника.","vi":"Chúng tôi làm áp phích cho lễ hội trường của chúng tôi.","fa":"ما برای جشنواره مدرسه خود پوستر درست کردیم."}]},{"word":"planen","en":"to plan","ru":"планировать","vi":"kế hoạch","fa":"برنامه ریزی کنید","examples":[{"de":"Wir planen eine Reise nach Italien.","en":"We are planning a trip to Italy.","ru":"Мы планируем поездку в Италию.","vi":"Chúng tôi đang lên kế hoạch cho một chuyến đi đến Ý.","fa":"ما قصد سفر به ایتالیا را داریم."},{"de":"Er plant seinen Tag immer genau.","en":"He always plans his day precisely.","ru":"Он всегда точно планирует свой день.","vi":"Anh ấy luôn lên kế hoạch cho ngày của mình một cách cẩn thận.","fa":"او همیشه روز خود را با دقت برنامه ریزی می کند."}]},{"word":"der Planet","en":"planet","ru":"планета","vi":"hành tinh","fa":"سیاره","examples":[{"de":"Der Mars ist der vierte Planet von der Sonne.","en":"Mars is the fourth planet from the sun.","ru":"Марс — четвёртая планета от Солнца.","vi":"Sao Hỏa là hành tinh thứ tư tính từ mặt trời.","fa":"مریخ چهارمین سیاره از خورشید است."},{"de":"Jeder Planet in unserem Sonnensystem bewegt sich auf einer eigenen Bahn.","en":"Every planet in our solar system moves along its own orbit.","ru":"Каждая планета в нашей Солнечной системе движется по своей орбите.","vi":"Mỗi hành tinh trong hệ mặt trời của chúng ta di chuyển trên quỹ đạo riêng của nó.","fa":"هر سیاره در منظومه شمسی ما در مدار خود حرکت می کند."},{"de":"Wissenschaftler suchen nach einem Planeten, auf dem flüssiges Wasser existieren könnte.","en":"Scientists are searching for a planet on which liquid water could exist.","ru":"Учёные ищут планету, на которой могла бы существовать жидкая вода.","vi":"Các nhà khoa học đang tìm kiếm một hành tinh có thể tồn tại nước ở dạng lỏng.","fa":"دانشمندان به دنبال سیاره ای هستند که در آن آب مایع وجود داشته باشد."}]},{"word":"die Planung","en":"planning","ru":"планирование","vi":"việc lập kế hoạch","fa":"برنامه ریزی","examples":[{"de":"Die Planung des Projekts hat mehrere Wochen gedauert.","en":"Planning the project took several weeks.","ru":"Планирование проекта заняло несколько недель.","vi":"Việc lập kế hoạch cho dự án mất vài tuần.","fa":"برنامه ریزی پروژه چندین هفته طول کشید."},{"de":"Bei der Planung der Reise hilft uns ein Reisebüro.","en":"A travel agency is helping us with the planning of the trip.","ru":"Турагентство помогает нам с планированием поездки.","vi":"Một công ty du lịch giúp chúng tôi lên kế hoạch cho chuyến đi.","fa":"آژانس مسافرتی به ما در برنامه ریزی سفر کمک می کند."},{"de":"Eine gute Planung spart später viel Zeit.","en":"Good planning saves a lot of time later.","ru":"Хорошее планирование потом экономит много времени.","vi":"Lập kế hoạch tốt sẽ tiết kiệm rất nhiều thời gian sau này.","fa":"برنامه ریزی خوب بعدا باعث صرفه جویی در زمان می شود."}]},{"word":"das Plastik","en":"plastic","ru":"пластик, пластмасса","vi":"nhựa","fa":"پلاستیک","examples":[{"de":"Die Flasche ist aus Plastik.","en":"The bottle is made of plastic.","ru":"Бутылка сделана из пластика.","vi":"Chai được làm bằng nhựa.","fa":"بطری از پلاستیک ساخته شده است."},{"de":"Wir sollten weniger Plastik verwenden.","en":"We should use less plastic.","ru":"Нам следует использовать меньше пластика.","vi":"Chúng ta nên sử dụng ít nhựa hơn.","fa":"باید از پلاستیک کمتر استفاده کنیم."}]},{"word":"der Platz","en":"place; square; seat","ru":"место; площадь","vi":"nơi","fa":"مکان","examples":[{"de":"Ist dieser Platz noch frei?","en":"Is this seat still free?","ru":"Это место ещё свободно?","vi":"Chỗ này còn trống không?","fa":"آیا این فضا هنوز موجود است؟"},{"de":"Auf dem Marktplatz gibt es heute viele Stände.","en":"There are many stalls on the market square today.","ru":"Сегодня на рыночной площади много ларьков.","vi":"Quảng trường chợ ngày nay có rất nhiều quầy hàng.","fa":"امروزه در میدان بازار غرفه های زیادی وجود دارد."}]},{"word":"plötzlich","en":"suddenly","ru":"внезапно, вдруг","vi":"đột nhiên","fa":"به طور ناگهانی","examples":[{"de":"Plötzlich begann es stark zu regnen.","en":"Suddenly it started to rain heavily.","ru":"Внезапно начался сильный дождь.","vi":"Đột nhiên trời bắt đầu mưa to.","fa":"ناگهان باران شدیدی شروع به باریدن کرد."},{"de":"Er stand plötzlich vor der Tür.","en":"He suddenly stood at the door.","ru":"Он вдруг оказался у двери.","vi":"Anh chợt đứng trước cửa.","fa":"ناگهان جلوی در ایستاد."}]},{"word":"der Podcast","en":"podcast","ru":"подкаст","vi":"podcast","fa":"پادکست","examples":[{"de":"Auf dem Weg zur Arbeit höre ich gern einen Podcast.","en":"On my way to work I like to listen to a podcast.","ru":"По дороге на работу я люблю слушать подкаст.","vi":"Tôi thích nghe podcast trên đường đi làm.","fa":"من دوست دارم در راه سر کار به پادکست گوش کنم."},{"de":"Dieser Podcast erscheint jede Woche neu.","en":"This podcast is released anew every week.","ru":"Этот подкаст выходит каждую неделю заново.","vi":"Podcast này được phát hành hàng tuần.","fa":"این پادکست هر هفته منتشر می شود."},{"de":"In dem Podcast geht es um deutsche Geschichte.","en":"The podcast is about German history.","ru":"Подкаст посвящён немецкой истории.","vi":"Podcast nói về lịch sử nước Đức.","fa":"این پادکست درباره تاریخ آلمان است."}]},{"word":"der Pokal","en":"cup, trophy","ru":"кубок (спортивный трофей)","vi":"cái cốc","fa":"فنجان","examples":[{"de":"Die Mannschaft gewann den Pokal nach einem spannenden Spiel.","en":"The team won the cup after an exciting match.","ru":"Команда выиграла кубок после напряжённого матча.","vi":"Đội đã giành cúp sau một trận đấu hấp dẫn.","fa":"این تیم پس از یک بازی هیجان انگیز قهرمان جام حذفی شد."},{"de":"Der goldene Pokal steht jetzt im Schrank des Vereins.","en":"The golden trophy is now in the club's cabinet.","ru":"Золотой кубок теперь стоит в шкафу клуба.","vi":"Chiếc cúp vàng hiện đang nằm trong tủ của câu lạc bộ.","fa":"جام طلایی اکنون در کمد باشگاه است."},{"de":"Sie hob den Pokal stolz in die Höhe.","en":"She proudly raised the trophy into the air.","ru":"Она гордо подняла кубок вверх.","vi":"Cô tự hào nâng cao chiếc cúp.","fa":"او با افتخار جام را بالا برد."}]},{"word":"die Politik","en":"politics, policy","ru":"политика","vi":"chính trị","fa":"سیاست","examples":[{"de":"Sie interessiert sich sehr für Politik.","en":"She is very interested in politics.","ru":"Она очень интересуется политикой.","vi":"Cô ấy rất quan tâm đến chính trị.","fa":"او علاقه زیادی به سیاست دارد."},{"de":"Die Politik der Regierung wird viel diskutiert.","en":"The government's policy is much discussed.","ru":"Политику правительства широко обсуждают.","vi":"Các chính sách của chính phủ được thảo luận rộng rãi.","fa":"سیاست های دولت به طور گسترده مورد بحث قرار می گیرد."}]},{"word":"der Politiker","en":"politician","ru":"политик","vi":"chính trị gia","fa":"the politician","examples":[{"de":"Der Politiker hielt eine lange Rede im Parlament.","en":"The politician gave a long speech in parliament.","ru":"Политик произнёс в парламенте долгую речь.","vi":"Chính trị gia đã có một bài phát biểu dài trước quốc hội.","fa":"این سیاستمدار در مجلس سخنرانی طولانی داشت."},{"de":"Viele Politiker versprechen vor der Wahl niedrigere Steuern.","en":"Many politicians promise lower taxes before the election.","ru":"Многие политики перед выборами обещают снизить налоги.","vi":"Nhiều chính trị gia đang hứa hẹn giảm thuế trước cuộc bầu cử.","fa":"بسیاری از سیاستمداران وعده کاهش مالیات را قبل از انتخابات می دهند."},{"de":"Ein guter Politiker hört seinen Bürgern zu.","en":"A good politician listens to his citizens.","ru":"Хороший политик прислушивается к своим гражданам.","vi":"Một chính trị gia giỏi lắng nghe công dân của mình.","fa":"یک سیاستمدار خوب به حرف شهروندانش گوش می دهد."}]},{"word":"die Politikerin","en":"politician (female)","ru":"политик (женщина)","vi":"chính trị gia","fa":"سیاستمدار","examples":[{"de":"Die Politikerin setzte sich für mehr Gleichheit ein.","en":"The politician campaigned for more equality.","ru":"Эта женщина-политик выступала за большее равенство.","vi":"Chính trị gia vận động cho sự bình đẳng hơn.","fa":"این سیاستمدار برای برابری بیشتر مبارزه کرد."},{"de":"Diese Politikerin ist in der ganzen Region bekannt.","en":"This politician is well known throughout the region.","ru":"Эту женщину-политика знают во всём регионе.","vi":"Chính trị gia này nổi tiếng khắp vùng.","fa":"این سیاستمدار در سراسر منطقه شناخته شده است."},{"de":"Die junge Politikerin gewann viele Stimmen.","en":"The young politician won many votes.","ru":"Молодой политик набрала много голосов.","vi":"Chính trị gia trẻ tuổi đã giành được nhiều phiếu bầu.","fa":"این سیاستمدار جوان آرای زیادی کسب کرد."}]},{"word":"politisch","en":"political","ru":"политический","vi":"chính trị","fa":"سیاسی","examples":[{"de":"Sie interessiert sich sehr für politische Themen.","en":"She is very interested in political topics.","ru":"Она очень интересуется политическими темами.","vi":"Cô ấy rất quan tâm đến các vấn đề chính trị.","fa":"او علاقه زیادی به مسائل سیاسی دارد."},{"de":"Die politische Lage im Land ist angespannt.","en":"The political situation in the country is tense.","ru":"Политическая обстановка в стране напряжённая.","vi":"Tình hình chính trị trong nước rất căng thẳng.","fa":"اوضاع سیاسی کشور متشنج است."},{"de":"Er traf eine wichtige politische Entscheidung.","en":"He made an important political decision.","ru":"Он принял важное политическое решение.","vi":"Ông đã đưa ra một quyết định chính trị quan trọng.","fa":"او تصمیم سیاسی مهمی گرفت."}]},{"word":"die Polizei","en":"police","ru":"полиция","vi":"cảnh sát","fa":"پلیس","examples":[{"de":"Wir haben den Unfall der Polizei gemeldet.","en":"We reported the accident to the police.","ru":"Мы сообщили о происшествии в полицию.","vi":"Chúng tôi đã báo cáo vụ tai nạn cho cảnh sát.","fa":"تصادف را به پلیس اطلاع دادیم."},{"de":"Die Polizei kontrolliert die Ausweise.","en":"The police check the IDs.","ru":"Полиция проверяет документы.","vi":"Cảnh sát kiểm tra giấy tờ tùy thân.","fa":"پلیس شناسنامه ها را بررسی می کند."}]},{"word":"der Polizist","en":"police officer (male)","ru":"полицейский (мужчина)","vi":"cảnh sát","fa":"پلیس","examples":[{"de":"Der Polizist hielt das Auto an und kontrollierte die Papiere.","en":"The police officer stopped the car and checked the documents.","ru":"Полицейский остановил машину и проверил документы.","vi":"Viên cảnh sát dừng xe và kiểm tra giấy tờ.","fa":"افسر پلیس ماشین را متوقف کرد و مدارک را چک کرد."},{"de":"Ich habe den Polizisten nach dem Weg gefragt.","en":"I asked the police officer for directions.","ru":"Я спросил у полицейского дорогу.","vi":"Tôi hỏi viên cảnh sát để được hướng dẫn.","fa":"از افسر پلیس راهنمایی خواستم."},{"de":"Als Kind wollte er Polizist werden.","en":"As a child he wanted to become a police officer.","ru":"В детстве он хотел стать полицейским.","vi":"Khi còn nhỏ anh muốn trở thành cảnh sát.","fa":"در کودکی می خواست افسر پلیس شود."}]},{"word":"die Polizistin","en":"police officer (female)","ru":"полицейская (женщина)","vi":"nữ cảnh sát","fa":"پلیس زن","examples":[{"de":"Die Polizistin half der alten Frau über die Straße.","en":"The police officer helped the old woman across the street.","ru":"Полицейская помогла пожилой женщине перейти улицу.","vi":"Nữ cảnh sát giúp bà lão qua đường.","fa":"زن پلیس آن طرف خیابان به پیرزن کمک کرد."},{"de":"Eine Polizistin erklärte uns, was passiert war.","en":"A police officer explained to us what had happened.","ru":"Полицейская объяснила нам, что произошло.","vi":"Một nữ cảnh sát giải thích cho chúng tôi chuyện gì đã xảy ra.","fa":"یک پلیس زن برای ما توضیح داد که چه اتفاقی افتاده است."},{"de":"Meine Schwester ist Polizistin in München.","en":"My sister is a police officer in Munich.","ru":"Моя сестра — полицейская в Мюнхене.","vi":"Em gái tôi là cảnh sát ở Munich.","fa":"خواهرم در مونیخ افسر پلیس است."}]},{"word":"die Pommes frites","en":"French fries","ru":"картофель фри","vi":"khoai tây chiên","fa":"سیب زمینی سرخ کرده","examples":[{"de":"Zum Mittagessen gibt es Pommes frites mit Ketchup.","en":"For lunch there are French fries with ketchup.","ru":"На обед картофель фри с кетчупом.","vi":"Bữa trưa chúng tôi dùng khoai tây chiên với sốt cà chua.","fa":"برای ناهار سیب زمینی سرخ کرده با سس کچاپ می خوریم."},{"de":"Die Kinder essen gern Pommes frites.","en":"The children like to eat French fries.","ru":"Дети любят есть картофель фри.","vi":"Bọn trẻ thích ăn khoai tây chiên kiểu Pháp.","fa":"بچه ها دوست دارند سیب زمینی سرخ کرده بخورند."}]},{"word":"populär","en":"popular","ru":"популярный","vi":"phổ biến","fa":"محبوب","examples":[{"de":"Dieser Sänger ist bei Jugendlichen sehr populär.","en":"This singer is very popular with young people.","ru":"Этот певец очень популярен среди молодёжи.","vi":"Ca sĩ này rất được giới trẻ yêu thích.","fa":"این خواننده محبوبیت زیادی در بین جوانان دارد."},{"de":"Fußball ist der populärste Sport in Deutschland.","en":"Football is the most popular sport in Germany.","ru":"Футбол — самый популярный вид спорта в Германии.","vi":"Bóng đá là môn thể thao phổ biến nhất ở Đức.","fa":"فوتبال محبوب ترین ورزش در آلمان است."}]},{"word":"das Portemonnaie","en":"purse, wallet","ru":"кошелёк, бумажник","vi":"cái ví","fa":"کیف پول","examples":[{"de":"Ich habe mein Portemonnaie zu Hause vergessen.","en":"I forgot my wallet at home.","ru":"Я забыл кошелёк дома.","vi":"Tôi quên ví ở nhà.","fa":"کیف پولم را در خانه فراموش کردم."},{"de":"Im Portemonnaie ist kein Bargeld mehr.","en":"There's no more cash left in the wallet.","ru":"В кошельке больше нет наличных.","vi":"Không còn tiền trong ví nữa.","fa":"پول نقد دیگری در کیف پول وجود ندارد."},{"de":"Sie nahm eine Münze aus dem Portemonnaie.","en":"She took a coin out of her purse.","ru":"Она достала из кошелька монету.","vi":"Cô lấy một đồng xu ra khỏi ví.","fa":"یک سکه از کیفش درآورد."}]},{"word":"das Portemonnaie/Portmonee","en":"wallet, purse","ru":"кошелёк","vi":"cái ví/ví","fa":"کیف پول / کیف پول","examples":[{"de":"Ich habe mein Portemonnaie zu Hause vergessen.","en":"I forgot my wallet at home.","ru":"Я забыл свой кошелёк дома.","vi":"Tôi quên ví ở nhà.","fa":"کیف پولم را در خانه فراموش کردم."},{"de":"In meinem Portmonee habe ich nur wenig Bargeld.","en":"I only have a little cash in my wallet.","ru":"В моём кошельке совсем мало наличных.","vi":"Tôi chỉ có một ít tiền mặt trong ví.","fa":"فقط کمی پول نقد در کیفم دارم."}]},{"word":"die Portion","en":"portion, serving","ru":"порция","vi":"phần","fa":"بخش","examples":[{"de":"Ich hätte gern eine Portion Pommes.","en":"I would like a portion of fries.","ru":"Я хотел бы одну порцию картофеля фри.","vi":"Tôi muốn một phần khoai tây chiên.","fa":"من یک قسمت سیب زمینی سرخ کرده می خواهم."},{"de":"Die Portionen in diesem Restaurant sind sehr groß.","en":"The portions in this restaurant are very large.","ru":"Порции в этом ресторане очень большие.","vi":"Các phần trong nhà hàng này rất lớn.","fa":"وعده های غذایی این رستوران بسیار زیاد است."}]},{"word":"das Portmonee","en":"purse, wallet","ru":"кошелёк, бумажник","vi":"cái ví","fa":"کیف پول","examples":[{"de":"Mein Portmonee ist in der Jackentasche.","en":"My wallet is in the jacket pocket.","ru":"Мой кошелёк в кармане куртки.","vi":"Ví của tôi ở trong túi áo khoác.","fa":"کیف پولم در جیب ژاکتم است."},{"de":"Er bezahlte und steckte das Portmonee wieder ein.","en":"He paid and put the wallet away again.","ru":"Он расплатился и снова убрал кошелёк.","vi":"Anh trả tiền và nhét ví lại vào túi.","fa":"پول داد و کیف پول را در جیبش گذاشت."},{"de":"Im Portmonee habe ich nur noch fünf Euro.","en":"I only have five euros left in my wallet.","ru":"У меня в кошельке осталось всего пять евро.","vi":"Tôi chỉ còn năm euro trong ví.","fa":"فقط پنج یورو در کیفم مانده است."}]},{"word":"die Position","en":"position","ru":"позиция, положение","vi":"vị trí","fa":"موقعیت","examples":[{"de":"Sie hat eine wichtige Position in der Firma.","en":"She holds an important position in the company.","ru":"Она занимает важную позицию в компании.","vi":"Cô ấy có một vị trí quan trọng trong công ty.","fa":"او موقعیت مهمی در شرکت دارد."},{"de":"Wechseln Sie bitte die Position des Bildschirms.","en":"Please change the position of the screen.","ru":"Измените, пожалуйста, положение экрана.","vi":"Hãy thay đổi vị trí của màn hình.","fa":"لطفا موقعیت صفحه را تغییر دهید."},{"de":"In dieser Frage habe ich eine klare Position.","en":"On this question I have a clear position.","ru":"По этому вопросу у меня чёткая позиция.","vi":"Tôi có quan điểm rõ ràng về vấn đề này.","fa":"من موضع روشنی در این مورد دارم."}]},{"word":"positiv","en":"positive","ru":"положительный","vi":"tích cực","fa":"مثبت","examples":[{"de":"Sie denkt immer positiv, auch in schweren Zeiten.","en":"She always thinks positively, even in hard times.","ru":"Она всегда мыслит позитивно, даже в трудные времена.","vi":"Cô luôn suy nghĩ tích cực, ngay cả trong những thời điểm khó khăn.","fa":"او همیشه مثبت فکر می کند، حتی در شرایط سخت."},{"de":"Der Test war positiv.","en":"The test was positive.","ru":"Тест оказался положительным.","vi":"Thử nghiệm cho kết quả dương tính.","fa":"آزمایش مثبت بود."}]},{"word":"die Post","en":"post office; mail","ru":"почта","vi":"bưu điện","fa":"اداره پست","examples":[{"de":"Ich gehe zur Post, um ein Paket abzuholen.","en":"I am going to the post office to pick up a package.","ru":"Я иду на почту забрать посылку.","vi":"Tôi đang đến bưu điện để lấy một gói hàng.","fa":"من میرم اداره پست تا یه بسته تحویل بگیرم."},{"de":"Heute habe ich viel Post bekommen.","en":"Today I got a lot of mail.","ru":"Сегодня я получил много почты.","vi":"Hôm nay tôi nhận được rất nhiều thư.","fa":"امروز نامه های زیادی دریافت کردم."}]},{"word":"posten","en":"to post content on a social network","ru":"постить, публиковать (контент в соцсети)","vi":"bài đăng","fa":"پست","examples":[{"de":"Man kann ein Bild posten und es jederzeit löschen.","en":"You can post a picture and delete it at any time.","ru":"Можно опубликовать картинку и в любой момент её удалить.","vi":"Bạn có thể đăng một bức ảnh và xóa nó bất cứ lúc nào.","fa":"هر زمان خواستید می توانید یک عکس ارسال کنید و آن را حذف کنید."},{"de":"Sie postet jeden Tag ein Foto von ihrem Essen.","en":"She posts a photo of her food every day.","ru":"Она каждый день постит фото своей еды.","vi":"Cô ấy đăng ảnh đồ ăn của mình mỗi ngày.","fa":"او هر روز عکسی از غذای خود منتشر می کند."},{"de":"Ich habe gerade einen langen Text über meine Reise gepostet.","en":"I've just posted a long text about my trip.","ru":"Я только что опубликовал длинный текст о своём путешествии.","vi":"Tôi vừa đăng một bài viết dài về chuyến đi của mình.","fa":"من فقط یک متن طولانی در مورد سفرم ارسال کردم."}]},{"word":"der Pöstler","en":"postman, mail carrier","ru":"почтальон","vi":"người đưa thư","fa":"پستچی","examples":[{"de":"Der Pöstler bringt jeden Morgen die Briefe.","en":"The postman brings the letters every morning.","ru":"Почтальон приносит письма каждое утро.","vi":"Người đưa thư mang thư đến mỗi sáng.","fa":"پستچی هر روز صبح نامه ها را می آورد."},{"de":"Ich habe den Pöstler heute vor dem Haus getroffen.","en":"I met the postman in front of the house today.","ru":"Сегодня я встретил почтальона перед домом.","vi":"Hôm nay tôi gặp người đưa thư trước nhà.","fa":"امروز جلوی در خانه با پستچی ملاقات کردم."}]},{"word":"das Poulet","en":"chicken (meat)","ru":"курица (мясо)","vi":"con gà","fa":"مرغ","examples":[{"de":"Zum Abendessen gibt es Poulet mit Reis.","en":"For dinner there is chicken with rice.","ru":"На ужин курица с рисом.","vi":"Bữa tối có cơm gà.","fa":"برای شام مرغ با برنج وجود دارد."},{"de":"Sie kauft frisches Poulet auf dem Markt.","en":"She buys fresh chicken at the market.","ru":"Она покупает свежую курицу на рынке.","vi":"Cô ấy mua gà tươi ở chợ.","fa":"او مرغ تازه را از بازار می خرد."}]},{"word":"die Praktikantin","en":"intern, trainee (female)","ru":"практикантка, стажёрка (женщина)","vi":"thực tập sinh","fa":"کارآموز","examples":[{"de":"Die Praktikantin lernt schnell und arbeitet sehr gut.","en":"The intern learns quickly and works very well.","ru":"Практикантка быстро учится и работает очень хорошо.","vi":"Thực tập sinh học nhanh và làm việc rất tốt.","fa":"کارآموز به سرعت یاد می گیرد و بسیار خوب کار می کند."},{"de":"Unsere neue Praktikantin kommt aus Spanien.","en":"Our new intern comes from Spain.","ru":"Наша новая практикантка из Испании.","vi":"Thực tập sinh mới của chúng tôi đến từ Tây Ban Nha.","fa":"کارآموز جدید ما از اسپانیا آمده است."},{"de":"Als Praktikantin half sie im Büro bei vielen Aufgaben.","en":"As an intern she helped with many tasks in the office.","ru":"Как практикантка она помогала со многими задачами в офисе.","vi":"Là một thực tập sinh, cô đã giúp đỡ nhiều công việc trong văn phòng.","fa":"به عنوان یک کارآموز، او در بسیاری از وظایف در دفتر کمک کرد."}]},{"word":"das Praktikum","en":"internship","ru":"стажировка, практика","vi":"thực tập","fa":"کارآموزی","examples":[{"de":"Ich mache im Sommer ein Praktikum bei einer Bank.","en":"I am doing an internship at a bank this summer.","ru":"Летом я прохожу стажировку в банке.","vi":"Tôi đang thực tập tại một ngân hàng vào mùa hè này.","fa":"تابستان امسال در یک بانک کارآموزی می کنم."},{"de":"Das Praktikum dauert drei Monate.","en":"The internship lasts three months.","ru":"Стажировка длится три месяца.","vi":"Thời gian thực tập kéo dài ba tháng.","fa":"دوره کارآموزی سه ماه به طول می انجامد."}]},{"word":"praktisch","en":"practical","ru":"практичный, удобный","vi":"thiết thực","fa":"عملی","examples":[{"de":"Diese Tasche ist sehr praktisch für die Reise.","en":"This bag is very practical for the trip.","ru":"Эта сумка очень удобна для поездки.","vi":"Chiếc túi này rất thiết thực cho việc đi du lịch.","fa":"این کیف برای مسافرت بسیار کاربردی است."},{"de":"Er löst Probleme immer praktisch und schnell.","en":"He always solves problems practically and quickly.","ru":"Он всегда решает проблемы практично и быстро.","vi":"Anh ấy luôn giải quyết vấn đề một cách thực tế và nhanh chóng.","fa":"او همیشه مشکلات را به صورت عملی و سریع حل می کند."}]},{"word":"die Präsentation","en":"presentation","ru":"презентация","vi":"bài thuyết trình","fa":"ارائه","examples":[{"de":"Morgen halte ich eine Präsentation über meine Reise.","en":"Tomorrow I'm giving a presentation about my trip.","ru":"Завтра я делаю презентацию о своей поездке.","vi":"Ngày mai tôi sẽ thuyết trình về chuyến đi của mình.","fa":"فردا درباره سفرم ارائه خواهم کرد."},{"de":"Die Präsentation war gut vorbereitet und sehr interessant.","en":"The presentation was well prepared and very interesting.","ru":"Презентация была хорошо подготовлена и очень интересна.","vi":"Bài thuyết trình đã được chuẩn bị tốt và rất thú vị.","fa":"ارائه به خوبی آماده و بسیار جالب بود."},{"de":"Für die Präsentation brauche ich einen Beamer.","en":"For the presentation I need a projector.","ru":"Для презентации мне нужен проектор.","vi":"Tôi cần một máy chiếu để thuyết trình.","fa":"برای ارائه به یک پروژکتور نیاز دارم."}]},{"word":"präsentieren","en":"to present","ru":"представлять, презентовать","vi":"hiện tại","fa":"حاضر","examples":[{"de":"Sie präsentiert ihr Projekt vor der ganzen Klasse.","en":"She presents her project to the whole class.","ru":"Она представляет свой проект перед всем классом.","vi":"Cô trình bày dự án của mình cho cả lớp.","fa":"او پروژه خود را به کل کلاس ارائه می دهد."},{"de":"Wir müssen unsere Ergebnisse morgen präsentieren.","en":"We have to present our results tomorrow.","ru":"Завтра нам нужно представить наши результаты.","vi":"Chúng ta phải trình bày kết quả vào ngày mai.","fa":"ما باید فردا نتایج خود را ارائه دهیم."}]},{"word":"die Praxis","en":"practice; doctor's office","ru":"практика; врачебный кабинет","vi":"thực hành","fa":"تمرین","examples":[{"de":"In der Praxis ist es oft anders als in der Theorie.","en":"In practice it is often different than in theory.","ru":"На практике часто всё иначе, чем в теории.","vi":"Trong thực tế nó thường khác so với lý thuyết.","fa":"در عمل اغلب با تئوری متفاوت است."},{"de":"Der Arzt hat seine Praxis in der Stadtmitte.","en":"The doctor has his practice in the city center.","ru":"У врача кабинет в центре города.","vi":"Bác sĩ có phòng khám ở trung tâm thành phố.","fa":"دکتر مطب خود را در مرکز شهر دارد."}]},{"word":"der Preis","en":"price; prize","ru":"цена; приз","vi":"giá cả","fa":"قیمت","examples":[{"de":"Der Preis für das Buch ist sehr hoch.","en":"The price of the book is very high.","ru":"Цена этой книги очень высока.","vi":"Giá sách rất cao.","fa":"قیمت کتاب بسیار بالاست."},{"de":"Sie hat den ersten Preis beim Wettbewerb gewonnen.","en":"She won first prize in the competition.","ru":"Она выиграла первый приз в конкурсе.","vi":"Cô đã giành giải nhất trong cuộc thi.","fa":"او در این مسابقه برنده جایزه اول شد."}]},{"word":"der Preisvergleich","en":"price comparison","ru":"сравнение цен","vi":"so sánh giá","fa":"مقایسه قیمت","examples":[{"de":"Vor dem Kauf mache ich immer einen Preisvergleich im Internet.","en":"Before buying I always do a price comparison on the internet.","ru":"Перед покупкой я всегда делаю сравнение цен в интернете.","vi":"Trước khi mua, tôi luôn so sánh giá cả trên mạng.","fa":"قبل از خرید همیشه قیمت ها را بصورت آنلاین مقایسه می کنم."},{"de":"Ein Preisvergleich lohnt sich, denn die Unterschiede sind groß.","en":"A price comparison is worthwhile, as the differences are big.","ru":"Сравнение цен стоит того, ведь разница большая.","vi":"Thật đáng để so sánh giá cả vì sự khác biệt là lớn.","fa":"ارزش مقایسه قیمت ها را دارد زیرا تفاوت ها زیاد است."},{"de":"Diese Webseite bietet einen schnellen Preisvergleich an.","en":"This website offers a quick price comparison.","ru":"Этот сайт предлагает быстрое сравнение цен.","vi":"Trang web này cung cấp một so sánh giá nhanh chóng.","fa":"این وب سایت مقایسه سریع قیمت را ارائه می دهد."}]},{"word":"die Presse","en":"the press (media)","ru":"пресса (СМИ)","vi":"báo chí","fa":"مطبوعات","examples":[{"de":"Die Presse berichtet heute über das Fußballspiel.","en":"The press reports on the football match today.","ru":"Пресса сегодня сообщает о футбольном матче.","vi":"Báo chí đang đưa tin về trận đấu bóng đá ngày hôm nay.","fa":"مطبوعات از بازی فوتبال امروز خبر می دهند."},{"de":"Viele Journalisten der Presse waren bei der Pressekonferenz.","en":"Many journalists from the press were at the press conference.","ru":"Много журналистов из прессы было на пресс-конференции.","vi":"Nhiều phóng viên báo chí có mặt tại buổi họp báo.","fa":"بسیاری از خبرنگاران مطبوعاتی در این نشست خبری حضور داشتند."}]},{"word":"prickelnd","en":"sparkling, tingling, fizzy","ru":"искристый, покалывающий, газированный","vi":"trêu chọc","fa":"گزگز","examples":[{"de":"Das prickelnde Getränk erfrischt an heißen Tagen.","en":"The fizzy drink refreshes you on hot days.","ru":"Газированный напиток освежает в жаркие дни.","vi":"Đồ uống có ga giúp giải khát trong những ngày nắng nóng.","fa":"نوشیدنی گازدار در روزهای گرم با طراوت است."},{"de":"Sie liebt den prickelnden Geschmack von Sekt.","en":"She loves the sparkling taste of sparkling wine.","ru":"Она любит искристый вкус игристого вина.","vi":"Cô ấy thích hương vị lấp lánh của rượu vang sủi.","fa":"او طعم گازدار شراب گازدار را دوست دارد."},{"de":"Ein prickelndes Wasser passt gut zum Essen.","en":"A sparkling water goes well with the meal.","ru":"Газированная вода хорошо подходит к еде.","vi":"Nước có ga rất hợp với thức ăn.","fa":"آب گازدار با غذا خوب می شود."}]},{"word":"prima","en":"great, excellent","ru":"отлично, здорово","vi":"tuyệt vời","fa":"عالی","examples":[{"de":"Das hast du prima gemacht!","en":"You did that great!","ru":"Ты отлично справился!","vi":"Bạn đã làm rất tốt!","fa":"عالی کار کردی"},{"de":"Das Wetter heute ist einfach prima.","en":"The weather today is simply excellent.","ru":"Погода сегодня просто отличная.","vi":"Thời tiết hôm nay thật tuyệt vời.","fa":"هوا امروز فقط عالیه"}]},{"word":"der Prinz","en":"prince","ru":"принц","vi":"hoàng tử","fa":"شاهزاده","examples":[{"de":"In dem Märchen rettet der Prinz die Prinzessin.","en":"In the fairy tale the prince rescues the princess.","ru":"В сказке принц спасает принцессу.","vi":"Trong truyện cổ tích, hoàng tử cứu công chúa.","fa":"در افسانه، شاهزاده شاهزاده خانم را نجات می دهد."},{"de":"Der junge Prinz wird eines Tages König.","en":"The young prince will one day be king.","ru":"Молодой принц однажды станет королём.","vi":"Hoàng tử trẻ một ngày nào đó sẽ trở thành vua.","fa":"شاهزاده جوان روزی پادشاه می شود."},{"de":"Sie tanzte mit dem Prinzen auf dem Ball.","en":"She danced with the prince at the ball.","ru":"Она танцевала с принцем на балу.","vi":"Cô khiêu vũ với hoàng tử tại vũ hội.","fa":"او با شاهزاده در رقص رقصید."}]},{"word":"privat","en":"private","ru":"частный, личный","vi":"riêng tư","fa":"خصوصی","examples":[{"de":"Das ist eine private Angelegenheit.","en":"That is a private matter.","ru":"Это личное дело.","vi":"Đây là một vấn đề riêng tư.","fa":"این یک موضوع خصوصی است."},{"de":"Er wohnt in einem privaten Haus außerhalb der Stadt.","en":"He lives in a private house outside the city.","ru":"Он живёт в частном доме за городом.","vi":"Anh sống ở một ngôi nhà riêng ở ngoại ô thành phố.","fa":"او در یک خانه شخصی خارج از شهر زندگی می کند."}]},{"word":"die Privatsphäre","en":"privacy","ru":"личное пространство, приватность","vi":"sự riêng tư","fa":"the privacy","examples":[{"de":"Im Hotel habe ich mehr Privatsphäre als bei einer Gastfamilie.","en":"In a hotel I have more privacy than with a host family.","ru":"В отеле у меня больше личного пространства, чем в принимающей семье.","vi":"Tôi có nhiều sự riêng tư hơn khi ở khách sạn so với ở gia đình bản xứ.","fa":"من در هتل حریم خصوصی بیشتری نسبت به خانواده میزبان دارم."},{"de":"Jeder Mensch braucht ein bisschen Privatsphäre.","en":"Everyone needs a bit of privacy.","ru":"Каждому нужно немного личного пространства.","vi":"Mọi người đều cần một chút riêng tư.","fa":"همه به کمی حریم خصوصی نیاز دارند."},{"de":"In einem Großraumbüro hat man kaum Privatsphäre.","en":"In an open-plan office you have hardly any privacy.","ru":"В открытом офисе почти нет приватности.","vi":"Trong một văn phòng có không gian mở, bạn hầu như không có bất kỳ sự riêng tư nào.","fa":"در یک دفتر با پلان باز شما به سختی حریم خصوصی دارید."}]},{"word":"pro","en":"per","ru":"за, на (каждый)","vi":"mỗi","fa":"در هر","examples":[{"de":"Das Zimmer kostet 80 Euro pro Nacht.","en":"The room costs 80 euros per night.","ru":"Номер стоит 80 евро за ночь.","vi":"Phòng có giá 80 euro mỗi đêm.","fa":"هزینه اتاق برای هر شب 80 یورو است."},{"de":"Wir treffen uns einmal pro Woche.","en":"We meet once per week.","ru":"Мы встречаемся раз в неделю.","vi":"Chúng tôi gặp nhau mỗi tuần một lần.","fa":"هفته ای یک بار همدیگر را ملاقات می کنیم."}]},{"word":"die Probezeit","en":"probationary period","ru":"испытательный срок","vi":"thời gian thử việc","fa":"دوره آزمایشی","examples":[{"de":"In der Probezeit kann man jederzeit gekündigt werden.","en":"During the probationary period you can be dismissed at any time.","ru":"Во время испытательного срока могут уволить в любой момент.","vi":"Trong thời gian thử việc bạn có thể bị sa thải bất cứ lúc nào.","fa":"در طول دوره آزمایشی شما می توانید در هر زمانی خاتمه دهید."},{"de":"Meine Probezeit dauert sechs Monate.","en":"My probationary period lasts six months.","ru":"Мой испытательный срок длится шесть месяцев.","vi":"Thời gian thử việc của tôi kéo dài sáu tháng.","fa":"دوره آزمایشی من شش ماه طول می کشد."},{"de":"Nach der Probezeit wurde sie fest angestellt.","en":"After the probationary period she was taken on permanently.","ru":"После испытательного срока её взяли на постоянную работу.","vi":"Sau thời gian thử việc, cô được tuyển dụng chính thức.","fa":"پس از دوره آزمایشی، او برای همیشه استخدام شد."}]},{"word":"probieren","en":"to try, to taste","ru":"пробовать","vi":"thử","fa":"سعی کنید","examples":[{"de":"Möchtest du meinen Kuchen probieren?","en":"Would you like to try my cake?","ru":"Хочешь попробовать мой пирог?","vi":"Bạn có muốn thử bánh của tôi không?","fa":"دوست داری کیک منو امتحان کنی؟"},{"de":"Ich probiere gern neue Rezepte aus.","en":"I like to try out new recipes.","ru":"Я люблю пробовать новые рецепты.","vi":"Tôi thích thử công thức nấu ăn mới.","fa":"من دوست دارم دستور العمل های جدید را امتحان کنم."}]},{"word":"das Problem","en":"problem","ru":"проблема","vi":"vấn đề","fa":"مشکل","examples":[{"de":"Wir haben ein kleines Problem mit dem Auto.","en":"We have a small problem with the car.","ru":"У нас небольшая проблема с машиной.","vi":"Chúng tôi có một chút vấn đề với chiếc xe.","fa":"ما با ماشین کمی مشکل داریم."},{"de":"Kein Problem, ich helfe dir gern.","en":"No problem, I'm happy to help you.","ru":"Не проблема, я с радостью помогу тебе.","vi":"Không có vấn đề gì, tôi rất sẵn lòng trợ giúp bạn.","fa":"مشکلی نیست، خوشحال می شوم به شما کمک کنم."}]},{"word":"das Produkt","en":"product (result of multiplication)","ru":"произведение (результат умножения)","vi":"sản phẩm","fa":"محصول","examples":[{"de":"Das Produkt von vier und fünf ist zwanzig.","en":"The product of four and five is twenty.","ru":"Произведение четырёх и пяти равно двадцати.","vi":"Tích của bốn và năm là hai mươi.","fa":"حاصل ضرب چهار و پنج بیست است."},{"de":"Bei der Multiplikation heißt das Ergebnis Produkt.","en":"In multiplication the result is called the product.","ru":"При умножении результат называют произведением.","vi":"Khi nhân, kết quả được gọi là tích.","fa":"هنگام ضرب به نتیجه حاصل ضرب می گویند."},{"de":"Das Produkt zweier negativer Zahlen ist positiv.","en":"The product of two negative numbers is positive.","ru":"Произведение двух отрицательных чисел положительно.","vi":"Tích của hai số âm là số dương.","fa":"حاصل ضرب دو عدد منفی مثبت است."}]},{"word":"die Produktion","en":"production","ru":"производство","vi":"sản xuất","fa":"تولید","examples":[{"de":"Die Produktion der neuen Autos beginnt nächsten Monat.","en":"Production of the new cars starts next month.","ru":"Производство новых машин начнётся в следующем месяце.","vi":"Việc sản xuất những chiếc xe mới sẽ bắt đầu vào tháng tới.","fa":"تولید خودروهای جدید از ماه آینده آغاز می شود."},{"de":"In dieser Fabrik läuft die Produktion rund um die Uhr.","en":"In this factory production runs around the clock.","ru":"На этом заводе производство идёт круглосуточно.","vi":"Việc sản xuất tại nhà máy này diễn ra suốt ngày đêm.","fa":"تولید در این کارخانه به صورت شبانه روزی انجام می شود."},{"de":"Die Produktion wurde wegen eines Streiks gestoppt.","en":"Production was halted because of a strike.","ru":"Производство остановили из-за забастовки.","vi":"Việc sản xuất bị ngừng lại do một cuộc đình công.","fa":"تولید به دلیل اعتصاب متوقف شد."}]},{"word":"produzieren","en":"to produce","ru":"производить","vi":"sản xuất","fa":"تولید کنند","examples":[{"de":"Die Fabrik produziert Autos für den ganzen Kontinent.","en":"The factory produces cars for the whole continent.","ru":"Фабрика производит автомобили для всего континента.","vi":"Nhà máy sản xuất ô tô cho toàn lục địa.","fa":"این کارخانه برای کل قاره خودرو تولید می کند."},{"de":"Dieser Bauer produziert biologisches Gemüse.","en":"This farmer produces organic vegetables.","ru":"Этот фермер производит органические овощи.","vi":"Nông dân này sản xuất rau hữu cơ.","fa":"این کشاورز سبزیجات ارگانیک تولید می کند."}]},{"word":"der Professor","en":"professor","ru":"профессор","vi":"giáo sư","fa":"پروفسور","examples":[{"de":"Der Professor hält heute eine Vorlesung über Geschichte.","en":"The professor is giving a lecture on history today.","ru":"Профессор сегодня читает лекцию по истории.","vi":"Hôm nay giáo sư sẽ giảng về lịch sử.","fa":"استاد امروز در مورد تاریخ سخنرانی می کند."},{"de":"Ich habe eine Frage an den Professor.","en":"I have a question for the professor.","ru":"У меня есть вопрос к профессору.","vi":"Tôi có một câu hỏi cho giáo sư.","fa":"من یک سوال از استاد دارم."}]},{"word":"die Professorin","en":"professor (female)","ru":"профессор (женщина)","vi":"giáo sư","fa":"پروفسور","examples":[{"de":"Die Professorin forscht über das Klima.","en":"The professor researches the climate.","ru":"Профессор исследует климат.","vi":"Giáo sư nghiên cứu về khí hậu.","fa":"استاد در مورد آب و هوا تحقیق می کند."},{"de":"Unsere Professorin ist sehr nett und hilfsbereit.","en":"Our professor is very kind and helpful.","ru":"Наша профессор очень добрая и отзывчивая.","vi":"Giáo sư của chúng tôi rất tốt bụng và hữu ích.","fa":"استاد ما بسیار خوب و مفید است."},{"de":"Die Professorin korrigierte unsere Prüfungen.","en":"The professor marked our exams.","ru":"Профессор проверила наши экзаменационные работы.","vi":"Giáo sư đã sửa bài kiểm tra của chúng tôi.","fa":"استاد امتحانات ما را تصحیح کرد."}]},{"word":"der Profi","en":"professional, pro","ru":"профессионал","vi":"chuyên nghiệp","fa":"حرفه ای","examples":[{"de":"Er spielt Tennis wie ein echter Profi.","en":"He plays tennis like a real professional.","ru":"Он играет в теннис как настоящий профессионал.","vi":"Anh ấy chơi quần vợt như một tay vợt chuyên nghiệp thực thụ.","fa":"او مانند یک حرفه ای واقعی تنیس بازی می کند."},{"de":"Für diese Arbeit brauchen wir einen Profi.","en":"For this job we need a professional.","ru":"Для этой работы нам нужен профессионал.","vi":"Chúng tôi cần một chuyên gia cho công việc này.","fa":"به یک متخصص برای این کار نیازمندیم."}]},{"word":"der Profisportler","en":"professional athlete (male)","ru":"профессиональный спортсмен (мужчина)","vi":"vận động viên chuyên nghiệp","fa":"ورزشکار حرفه ای","examples":[{"de":"Als Profisportler trainiert er jeden Tag mehrere Stunden.","en":"As a professional athlete he trains several hours every day.","ru":"Как профессиональный спортсмен он каждый день тренируется по несколько часов.","vi":"Là một vận động viên chuyên nghiệp, anh tập luyện vài giờ mỗi ngày.","fa":"او به عنوان یک ورزشکار حرفه ای، هر روز چندین ساعت تمرین می کند."},{"de":"Viele Profisportler müssen sehr diszipliniert leben.","en":"Many professional athletes have to live very disciplined lives.","ru":"Многим профессиональным спортсменам приходится жить очень дисциплинированно.","vi":"Nhiều vận động viên chuyên nghiệp phải rất kỷ luật.","fa":"بسیاری از ورزشکاران حرفه ای باید بسیار منظم باشند."},{"de":"Der Profisportler verletzte sich beim Wettkampf.","en":"The professional athlete got injured during the competition.","ru":"Профессиональный спортсмен получил травму во время соревнования.","vi":"Vận động viên chuyên nghiệp bị thương trong quá trình thi đấu.","fa":"این ورزشکار حرفه ای در جریان مسابقات مصدوم شد."}]},{"word":"die Profisportlerin","en":"professional female athlete","ru":"профессиональная спортсменка","vi":"vận động viên chuyên nghiệp","fa":"ورزشکار حرفه ای","examples":[{"de":"Sie ist eine bekannte Profisportlerin aus Deutschland.","en":"She is a well-known professional athlete from Germany.","ru":"Она известная профессиональная спортсменка из Германии.","vi":"Cô là một vận động viên chuyên nghiệp nổi tiếng đến từ Đức.","fa":"او یک ورزشکار حرفه ای شناخته شده از آلمان است."},{"de":"Als Profisportlerin trainiert sie jeden Tag mehrere Stunden.","en":"As a professional athlete she trains for several hours every day.","ru":"Как профессиональная спортсменка, она тренируется по несколько часов каждый день.","vi":"Là một vận động viên chuyên nghiệp, cô tập luyện vài giờ mỗi ngày.","fa":"او به عنوان یک ورزشکار حرفه ای، هر روز چندین ساعت تمرین می کند."}]},{"word":"das Programm","en":"program","ru":"программа","vi":"chương trình","fa":"برنامه","examples":[{"de":"Das Programm für den Abend beginnt um acht Uhr.","en":"The program for the evening starts at eight o'clock.","ru":"Программа вечера начинается в восемь часов.","vi":"Chương trình buổi tối bắt đầu lúc tám giờ.","fa":"برنامه عصر از ساعت هشت شروع می شود."},{"de":"Ich habe ein neues Programm auf meinem Computer installiert.","en":"I installed a new program on my computer.","ru":"Я установил новую программу на свой компьютер.","vi":"Tôi đã cài đặt một chương trình mới trên máy tính của tôi.","fa":"من یک برنامه جدید روی کامپیوترم نصب کردم."}]},{"word":"programmieren","en":"to program, to code","ru":"программировать, писать код","vi":"chương trình","fa":"برنامه","examples":[{"de":"Sie lernt gerade, in Python zu programmieren.","en":"She is currently learning to program in Python.","ru":"Она сейчас учится программировать на Python.","vi":"Cô hiện đang học lập trình bằng Python.","fa":"او در حال حاضر در حال یادگیری برنامه نویسی در پایتون است."},{"de":"Mein Bruder hat sich selbst beigebracht, Apps zu programmieren.","en":"My brother taught himself to program apps.","ru":"Мой брат сам научился программировать приложения.","vi":"Anh trai tôi đã tự học lập trình ứng dụng.","fa":"My brother taught himself to program apps."},{"de":"Wer gut programmieren kann, findet heute leicht eine Stelle.","en":"Anyone who can program well easily finds a job nowadays.","ru":"Тот, кто хорошо умеет программировать, сегодня легко находит работу.","vi":"Bất cứ ai giỏi lập trình đều có thể dễ dàng tìm được việc làm ngày nay.","fa":"هرکسی که در برنامه نویسی مهارت داشته باشد می تواند امروز به راحتی شغل پیدا کند."}]},{"word":"die Programmoberfläche","en":"program interface","ru":"интерфейс программы (пользовательский)","vi":"giao diện chương trình","fa":"رابط برنامه","examples":[{"de":"Die neue Programmoberfläche ist viel übersichtlicher.","en":"The new program interface is much clearer.","ru":"Новый интерфейс программы гораздо нагляднее.","vi":"Giao diện chương trình mới rõ ràng hơn nhiều.","fa":"رابط برنامه جدید بسیار واضح تر است."},{"de":"Man gewöhnt sich schnell an die Programmoberfläche.","en":"You quickly get used to the program interface.","ru":"К интерфейсу программы быстро привыкаешь.","vi":"Bạn nhanh chóng làm quen với giao diện chương trình.","fa":"شما به سرعت به رابط برنامه عادت می کنید."},{"de":"Die Programmoberfläche lässt sich nach Wunsch anpassen.","en":"The program interface can be customised as you like.","ru":"Интерфейс программы можно настроить по желанию.","vi":"Giao diện chương trình có thể tùy chỉnh theo ý muốn.","fa":"رابط برنامه را می توان به دلخواه شخصی سازی کرد."}]},{"word":"das Projekt","en":"project","ru":"проект","vi":"dự án","fa":"پروژه","examples":[{"de":"Wir arbeiten zusammen an einem neuen Projekt.","en":"We are working together on a new project.","ru":"Мы вместе работаем над новым проектом.","vi":"Chúng tôi đang cùng nhau thực hiện một dự án mới.","fa":"ما با هم روی یک پروژه جدید کار می کنیم."},{"de":"Das Projekt soll bis Ende des Jahres fertig sein.","en":"The project is supposed to be finished by the end of the year.","ru":"Проект должен быть завершён до конца года.","vi":"Dự kiến ​​dự án sẽ hoàn thành vào cuối năm nay.","fa":"پیش بینی می شود این پروژه تا پایان سال به اتمام برسد."}]},{"word":"die Projektwoche","en":"project week (at school)","ru":"проектная неделя (в школе)","vi":"tuần dự án","fa":"هفته پروژه","examples":[{"de":"In der Projektwoche beschäftigen wir uns mit dem Thema Umwelt.","en":"During the project week we deal with the topic of the environment.","ru":"На проектной неделе мы занимаемся темой окружающей среды.","vi":"Trong tuần dự án, chúng tôi đề cập đến chủ đề môi trường.","fa":"در هفته پروژه به موضوع محیط زیست می پردازیم."},{"de":"Die Schüler freuen sich auf die Projektwoche.","en":"The pupils are looking forward to the project week.","ru":"Ученики с нетерпением ждут проектной недели.","vi":"Các sinh viên đang mong chờ tuần dự án.","fa":"دانش آموزان مشتاقانه منتظر هفته پروژه هستند."},{"de":"Während der Projektwoche gibt es keinen normalen Unterricht.","en":"During the project week there are no normal lessons.","ru":"Во время проектной недели обычных уроков нет.","vi":"Không có bài học bình thường trong tuần dự án.","fa":"هیچ درس عادی در طول هفته پروژه وجود ندارد."}]},{"word":"der Prospekt","en":"brochure, prospectus","ru":"проспект, брошюра","vi":"bản cáo bạch","fa":"دفترچه","examples":[{"de":"Im Reisebüro liegen viele bunte Prospekte.","en":"There are many colorful brochures in the travel agency.","ru":"В турагентстве лежит много красочных брошюр.","vi":"Có rất nhiều tài liệu quảng cáo đầy màu sắc trong công ty du lịch.","fa":"بروشورهای رنگارنگ زیادی در آژانس مسافرتی وجود دارد."},{"de":"Ich habe einen Prospekt über die neuen Möbel mitgenommen.","en":"I took a brochure about the new furniture.","ru":"Я взял брошюру о новой мебели.","vi":"Tôi mang theo một tập tài liệu quảng cáo về đồ nội thất mới.","fa":"یک بروشور در مورد مبلمان جدید با خودم بردم."}]},{"word":"Prost","en":"cheers!","ru":"будем здоровы!, ваше здоровье!","vi":"Chúc mừng","fa":"به سلامتی","examples":[{"de":"Prost! Auf deine Gesundheit!","en":"Cheers! To your health!","ru":"Будем здоровы! За твоё здоровье!","vi":"Chúc mừng! Vì sức khỏe của bạn!","fa":"به سلامتی به سلامتی شما!"},{"de":"Wir heben die Gläser und rufen: Prost!","en":"We raise our glasses and shout: Cheers!","ru":"Мы поднимаем бокалы и кричим: Будем здоровы!","vi":"Chúng tôi nâng ly và hét lên: Chúc mừng!","fa":"عینکمان را بلند می کنیم و فریاد می زنیم: به سلامتی!"}]},{"word":"prosten","en":"to drink a toast, say cheers","ru":"чокаться, произносить тост","vi":"chúc mừng","fa":"به سلامتی","examples":[{"de":"Wir prosteten dem Brautpaar zu.","en":"We drank a toast to the bride and groom.","ru":"Мы подняли тост за молодожёнов.","vi":"Chúng tôi nâng cốc chúc mừng cô dâu và chú rể.","fa":"عروس و داماد را برشته کردیم."},{"de":"Zum Jahreswechsel prosten sich alle zu.","en":"At the turn of the year everyone toasts one another.","ru":"В новогоднюю ночь все чокаются друг с другом.","vi":"Mọi người nâng cốc chúc mừng nhau vào dịp đầu năm.","fa":"در آغاز سال همه از یکدیگر نان تست می زنند."},{"de":"Sie hoben die Gläser und prosteten fröhlich.","en":"They raised their glasses and toasted cheerfully.","ru":"Они подняли бокалы и весело чокнулись.","vi":"Họ nâng ly và nâng cốc chúc mừng một cách vui vẻ.","fa":"لیوان هایشان را بالا آوردند و با خوشحالی نان تست کردند."}]},{"word":"der Protest","en":"protest","ru":"протест","vi":"cuộc biểu tình","fa":"اعتراض","examples":[{"de":"Der Protest gegen die Reform wurde immer größer.","en":"The protest against the reform grew bigger and bigger.","ru":"Протест против реформы становился всё сильнее.","vi":"Cuộc biểu tình phản đối cải cách ngày càng lớn hơn.","fa":"اعتراض به اصلاحات بیشتر شد."},{"de":"Aus Protest verließen die Abgeordneten den Saal.","en":"In protest the members left the hall.","ru":"В знак протеста депутаты покинули зал.","vi":"Các nghị sĩ rời khỏi phòng để phản đối.","fa":"نمایندگان مجلس در اعتراض به این موضوع اتاق را ترک کردند."},{"de":"Die Bürger äußerten ihren Protest auf der Straße.","en":"The citizens voiced their protest in the streets.","ru":"Граждане выразили свой протест на улицах.","vi":"Người dân bày tỏ sự phản đối trên đường phố.","fa":"شهروندان اعتراض خود را در خیابان ها ابراز کردند."}]},{"word":"protestieren","en":"to protest","ru":"протестовать","vi":"phản đối","fa":"اعتراض","examples":[{"de":"Die Studenten protestieren gegen die neuen Regeln.","en":"The students are protesting against the new rules.","ru":"Студенты протестуют против новых правил.","vi":"Các sinh viên đang phản đối các quy định mới.","fa":"اعتراض دانشجویان به قوانین جدید"},{"de":"Er protestierte laut gegen die Entscheidung.","en":"He protested loudly against the decision.","ru":"Он громко протестовал против этого решения.","vi":"Anh lớn tiếng phản đối quyết định này.","fa":"او با صدای بلند به این تصمیم اعتراض کرد."}]},{"word":"der Prozentsatz","en":"percentage rate","ru":"процентная ставка, процент","vi":"tỷ lệ phần trăm","fa":"درصد","examples":[{"de":"Der Prozentsatz der bestandenen Prüfungen lag bei achtzig.","en":"The percentage of passed exams was eighty.","ru":"Процент сданных экзаменов составил восемьдесят.","vi":"Tỷ lệ bài thi đậu là tám mươi.","fa":"درصد قبولی در امتحانات هشتاد بود."},{"de":"Wir berechneten den Prozentsatz der Rabatte.","en":"We calculated the percentage of the discounts.","ru":"Мы вычислили процент скидок.","vi":"Chúng tôi đã tính toán tỷ lệ phần trăm giảm giá.","fa":"درصد تخفیف ها را محاسبه کردیم."},{"de":"Ein höherer Prozentsatz bedeutet einen größeren Anteil.","en":"A higher percentage means a larger share.","ru":"Больший процент означает большую долю.","vi":"Tỷ lệ phần trăm cao hơn có nghĩa là tỷ lệ chia sẻ lớn hơn.","fa":"درصد بالاتر به معنای سهم بیشتر است."}]},{"word":"der Prozess","en":"process; trial (legal)","ru":"процесс; судебный процесс","vi":"quá trình","fa":"روند","examples":[{"de":"Der Prozess des Lernens dauert das ganze Leben.","en":"The process of learning lasts a whole lifetime.","ru":"Процесс обучения длится всю жизнь.","vi":"Quá trình học tập kéo dài suốt cuộc đời.","fa":"فرآیند یادگیری در طول زندگی ادامه دارد."},{"de":"Der Prozess gegen den Mann beginnt nächste Woche.","en":"The trial against the man begins next week.","ru":"Судебный процесс над этим человеком начинается на следующей неделе.","vi":"Phiên tòa xét xử người đàn ông này sẽ bắt đầu vào tuần tới.","fa":"محاکمه این مرد هفته آینده آغاز می شود."}]},{"word":"prüfen","en":"to check, to examine","ru":"проверять","vi":"kiểm tra","fa":"بررسی کنید","examples":[{"de":"Der Lehrer prüft die Hausaufgaben der Schüler.","en":"The teacher checks the students' homework.","ru":"Учитель проверяет домашние задания учеников.","vi":"Giáo viên kiểm tra bài tập về nhà của học sinh.","fa":"معلم تکالیف دانش آموزان را بررسی می کند."},{"de":"Bitte prüfen Sie Ihre Angaben, bevor Sie das Formular abschicken.","en":"Please check your details before you send the form.","ru":"Пожалуйста, проверьте свои данные, прежде чем отправить форму.","vi":"Vui lòng kiểm tra thông tin chi tiết của bạn trước khi gửi biểu mẫu.","fa":"لطفا قبل از ارسال فرم مشخصات خود را بررسی کنید."}]},{"word":"die Prüfung","en":"exam; test","ru":"экзамен; проверка","vi":"kỳ thi","fa":"امتحان","examples":[{"de":"Ich habe die Prüfung mit einer guten Note bestanden.","en":"I passed the exam with a good grade.","ru":"Я сдал экзамен на хорошую оценку.","vi":"Tôi đã vượt qua kỳ thi với điểm cao.","fa":"من در امتحان با نمره خوب قبول شدم."},{"de":"Vor der Prüfung war sie sehr nervös.","en":"Before the exam she was very nervous.","ru":"Перед экзаменом она сильно нервничала.","vi":"Cô ấy rất lo lắng trước kỳ thi.","fa":"قبل از امتحان خیلی عصبی بود."}]},{"word":"das Publikum","en":"audience","ru":"публика, зрители","vi":"khán giả","fa":"مخاطب","examples":[{"de":"Das Publikum applaudierte lange nach dem Konzert.","en":"The audience applauded for a long time after the concert.","ru":"Публика долго аплодировала после концерта.","vi":"Khán giả vỗ tay rất lâu sau buổi hòa nhạc.","fa":"تماشاگران مدت ها بعد از کنسرت کف زدند."},{"de":"Im Theater saß ein großes Publikum.","en":"A large audience sat in the theater.","ru":"В театре сидела большая публика.","vi":"Có một lượng lớn khán giả trong rạp.","fa":"تماشاگران زیادی در تئاتر حضور داشتند."}]},{"word":"der Pullover","en":"sweater, pullover","ru":"свитер, пуловер","vi":"chiếc áo len","fa":"ژاکت","examples":[{"de":"Im Winter trage ich einen warmen Pullover.","en":"In winter I wear a warm sweater.","ru":"Зимой я ношу тёплый свитер.","vi":"Vào mùa đông tôi mặc áo len ấm áp.","fa":"در زمستان یک ژاکت گرم می پوشم."},{"de":"Sie hat mir einen blauen Pullover geschenkt.","en":"She gave me a blue sweater as a present.","ru":"Она подарила мне синий свитер.","vi":"Cô ấy đưa cho tôi một chiếc áo len màu xanh.","fa":"یک ژاکت آبی به من داد."}]},{"word":"der Pumps","en":"court shoe, pump (high-heeled shoe)","ru":"туфли-лодочки (на каблуке)","vi":"máy bơm","fa":"پمپ ها","examples":[{"de":"Zu dem Kleid trägt sie schwarze Pumps.","en":"With the dress she wears black court shoes.","ru":"К платью она надевает чёрные туфли-лодочки.","vi":"Cô ấy đi giày cao gót màu đen với chiếc váy.","fa":"او با لباس تلمبه های مشکی می پوشد."},{"de":"Diese Pumps sind sehr elegant, aber unbequem.","en":"These court shoes are very elegant but uncomfortable.","ru":"Эти туфли-лодочки очень элегантные, но неудобные.","vi":"Những máy bơm này rất thanh lịch nhưng không thoải mái.","fa":"این پمپ ها بسیار ظریف اما ناراحت کننده هستند."},{"de":"Sie kaufte sich rote Pumps für die Feier.","en":"She bought herself red court shoes for the celebration.","ru":"Она купила себе красные туфли-лодочки на праздник.","vi":"Cô ấy mua đôi giày cao gót màu đỏ cho bữa tiệc.","fa":"او برای مهمانی پمپ های قرمز خرید."}]},{"word":"der Punkt","en":"point; dot","ru":"точка; пункт","vi":"điểm","fa":"نقطه","examples":[{"de":"Setz am Ende des Satzes einen Punkt.","en":"Put a period at the end of the sentence.","ru":"Поставь точку в конце предложения.","vi":"Đặt dấu chấm ở cuối câu.","fa":"در پایان جمله نقطه بگذارید."},{"de":"Das war ein wichtiger Punkt in der Diskussion.","en":"That was an important point in the discussion.","ru":"Это был важный пункт в дискуссии.","vi":"Đó là một điểm quan trọng trong cuộc thảo luận.","fa":"این یک نکته مهم در بحث بود."}]},{"word":"der Punsch","en":"punch (hot spiced drink)","ru":"пунш (горячий пряный напиток)","vi":"cú đấm","fa":"مشت","examples":[{"de":"Auf dem Weihnachtsmarkt gibt es heißen Punsch.","en":"At the Christmas market there is hot punch.","ru":"На рождественском рынке есть горячий пунш.","vi":"Có cú đấm nóng ở chợ Giáng sinh.","fa":"در بازار کریسمس پانچ داغ وجود دارد."},{"de":"Der Punsch wärmt einen an kalten Wintertagen.","en":"The punch warms you up on cold winter days.","ru":"Пунш согревает в холодные зимние дни.","vi":"Cú đấm sưởi ấm bạn vào những ngày mùa đông lạnh giá.","fa":"پانچ شما را در روزهای سرد زمستان گرم می کند."},{"de":"Für die Kinder kochen wir einen Punsch ohne Alkohol.","en":"For the children we make a punch without alcohol.","ru":"Для детей мы варим пунш без алкоголя.","vi":"Chúng tôi làm một loại rượu punch không cồn cho trẻ em.","fa":"برای بچه ها پانچ بدون الکل درست می کنیم."}]},{"word":"die Puppe","en":"doll","ru":"кукла","vi":"con búp bê","fa":"عروسک","examples":[{"de":"Das Mädchen spielt gern mit ihrer Puppe.","en":"The girl likes to play with her doll.","ru":"Девочка любит играть со своей куклой.","vi":"Cô bé thích chơi với búp bê của mình.","fa":"دختر دوست دارد با عروسکش بازی کند."},{"de":"Zum Geburtstag hat sie eine neue Puppe bekommen.","en":"For her birthday she got a new doll.","ru":"На день рождения она получила новую куклу.","vi":"Cô ấy có một con búp bê mới vào ngày sinh nhật của mình.","fa":"او برای تولدش یک عروسک جدید گرفت."}]},{"word":"putzen","en":"to clean","ru":"убирать, чистить","vi":"sạch sẽ","fa":"تمیز کردن","examples":[{"de":"Am Samstag putze ich immer die ganze Wohnung.","en":"On Saturdays I always clean the whole apartment.","ru":"По субботам я всегда убираю всю квартиру.","vi":"Tôi luôn dọn dẹp toàn bộ căn hộ vào thứ bảy.","fa":"من همیشه شنبه کل آپارتمان را تمیز می کنم."},{"de":"Kannst du bitte die Fenster putzen?","en":"Can you please clean the windows?","ru":"Ты можешь, пожалуйста, помыть окна?","vi":"Bạn có thể vui lòng lau cửa sổ được không?","fa":"میشه لطفا پنجره ها رو تمیز کنید؟"}]},{"word":"das Quali","en":"qualifying school-leaving certificate (informal, Quali­fizierender Mittelschulabschluss)","ru":"квалификационный аттестат об окончании средней школы (разговорное, Quali)","vi":"chất lượng","fa":"کیفیت","examples":[{"de":"Ohne das Quali findet man nur schwer eine Lehrstelle.","en":"Without the qualifying certificate it is hard to find an apprenticeship.","ru":"Без квалификационного аттестата трудно найти место для обучения.","vi":"Không có bằng cấp thì khó tìm được việc làm.","fa":"بدون صلاحیت، یافتن کارآموزی دشوار است."},{"de":"Mein Bruder hat das Quali mit guten Noten bestanden.","en":"My brother passed the qualifying certificate with good marks.","ru":"Мой брат сдал квалификационный аттестат с хорошими оценками.","vi":"Anh trai tôi đã vượt qua vòng loại với điểm số tốt.","fa":"برادرم صلاحیت را با نمرات خوب گذراند."},{"de":"Für diese Ausbildung brauchst du mindestens das Quali.","en":"For this training you need at least the qualifying certificate.","ru":"Для этого обучения нужен как минимум квалификационный аттестат.","vi":"Đối với khóa đào tạo này, bạn cần ít nhất trình độ chuyên môn.","fa":"برای این آموزش حداقل به مدرک نیاز دارید."}]},{"word":"die Qualifikation","en":"qualification","ru":"квалификация","vi":"trình độ chuyên môn","fa":"صلاحیت","examples":[{"de":"Für diese Stelle braucht man eine besondere Qualifikation.","en":"For this position you need a special qualification.","ru":"Для этой должности нужна особая квалификация.","vi":"Bạn cần có bằng cấp đặc biệt cho vị trí này.","fa":"برای این موقعیت به مدرک خاصی نیاز دارید."},{"de":"Seine Qualifikation als Techniker hilft ihm im neuen Job.","en":"His qualification as a technician helps him in the new job.","ru":"Его квалификация техника помогает ему на новой работе.","vi":"Trình độ kỹ thuật viên của anh ấy giúp anh ấy trong công việc mới.","fa":"صلاحیت های او به عنوان یک تکنسین به او در شغل جدید کمک می کند."}]},{"word":"die Qualität","en":"quality","ru":"качество","vi":"chất lượng","fa":"کیفیت","examples":[{"de":"Dieses Produkt hat eine sehr gute Qualität.","en":"This product has very good quality.","ru":"У этого продукта очень хорошее качество.","vi":"Sản phẩm này có chất lượng rất tốt.","fa":"این محصول کیفیت بسیار خوبی دارد."},{"de":"Wir legen großen Wert auf Qualität.","en":"We place great value on quality.","ru":"Мы придаём большое значение качеству.","vi":"Chúng tôi rất coi trọng chất lượng.","fa":"ما به کیفیت اهمیت زیادی می دهیم."}]},{"word":"das Quartier","en":"neighborhood, quarter; accommodation","ru":"квартал, район; жильё","vi":"khu phố; chỗ ở","fa":"ربع","examples":[{"de":"Wir wohnen in einem ruhigen Quartier der Stadt.","en":"We live in a quiet neighborhood of the city.","ru":"Мы живём в тихом районе города.","vi":"Chúng tôi sống ở một khu vực yên tĩnh của thành phố.","fa":"ما در یک منطقه آرام از شهر زندگی می کنیم."},{"de":"Die Soldaten suchten ein Quartier für die Nacht.","en":"The soldiers looked for accommodation for the night.","ru":"Солдаты искали ночлег на ночь.","vi":"Những người lính đang tìm nơi trú ẩn qua đêm.","fa":"سربازان به دنبال محل اقامت شبانه بودند."}]},{"word":"die Quelle","en":"source; spring","ru":"источник","vi":"nguồn","fa":"منبع","examples":[{"de":"Die Sonne ist eine wichtige Quelle für saubere Energie.","en":"The sun is an important source of clean energy.","ru":"Солнце — важный источник чистой энергии.","vi":"Mặt trời là nguồn năng lượng sạch quan trọng.","fa":"خورشید منبع مهم انرژی پاک است."},{"de":"Bitte gib in deinem Text immer die Quelle an.","en":"Please always cite the source in your text.","ru":"Пожалуйста, всегда указывай источник в своём тексте.","vi":"Hãy luôn trích dẫn nguồn trong văn bản của bạn.","fa":"لطفا همیشه منبع را در متن خود ذکر کنید."}]},{"word":"quer","en":"diagonally, crosswise","ru":"поперёк, наискосок","vi":"ngang qua","fa":"در سراسر","examples":[{"de":"Das Auto stand quer auf der Straße.","en":"The car was parked crosswise on the street.","ru":"Машина стояла поперёк улицы.","vi":"Chiếc xe đã đậu bên kia đường.","fa":"ماشین آن طرف خیابان پارک شده بود."},{"de":"Wir gehen quer durch den Park.","en":"We are walking diagonally across the park.","ru":"Мы идём наискосок через парк.","vi":"Chúng tôi đi bộ ngang qua công viên.","fa":"از پارک عبور می کنیم."}]},{"word":"der Quereinsteiger","en":"career changer; someone entering a profession from a different field","ru":"человек, сменивший профессию; пришедший в профессию из другой сферы","vi":"người thay đổi nghề nghiệp","fa":"تغییر دهنده شغل","examples":[{"de":"Als Quereinsteiger arbeitet er jetzt als Lehrer.","en":"As a career changer he now works as a teacher.","ru":"Сменив профессию, он теперь работает учителем.","vi":"Là một người thay đổi nghề nghiệp, hiện anh đang làm giáo viên.","fa":"او به عنوان یک تغییر شغل، اکنون به عنوان معلم کار می کند."},{"de":"Viele Quereinsteiger bringen wertvolle Erfahrung mit.","en":"Many career changers bring valuable experience with them.","ru":"Многие, кто сменил профессию, приносят с собой ценный опыт.","vi":"Nhiều người thay đổi nghề nghiệp mang theo những kinh nghiệm quý báu.","fa":"بسیاری از افراد تغییر شغل، تجربیات ارزشمندی را با خود به ارمغان می آورند."},{"de":"Die Firma stellt gern Quereinsteiger ein.","en":"The company likes to hire career changers.","ru":"Компания охотно нанимает тех, кто сменил профессию.","vi":"Công ty thích tuyển dụng những người thay đổi nghề nghiệp.","fa":"این شرکت دوست دارد افراد تغییر شغل را استخدام کند."}]},{"word":"die Quittung","en":"receipt","ru":"квитанция, чек","vi":"biên nhận","fa":"رسید","examples":[{"de":"Bitte geben Sie mir eine Quittung für den Einkauf.","en":"Please give me a receipt for the purchase.","ru":"Пожалуйста, дайте мне чек за покупку.","vi":"Vui lòng đưa cho tôi biên lai mua hàng.","fa":"لطفا رسید خرید را به من بدهید."},{"de":"Ich habe die Quittung leider verloren.","en":"Unfortunately I lost the receipt.","ru":"К сожалению, я потерял чек.","vi":"Thật không may tôi đã làm mất biên nhận.","fa":"متأسفانه رسید را گم کردم."}]},{"word":"das Quiz","en":"quiz","ru":"викторина","vi":"bài kiểm tra","fa":"مسابقه","examples":[{"de":"Wir spielen heute Abend ein Quiz über Geografie.","en":"This evening we are playing a quiz about geography.","ru":"Сегодня вечером мы играем в викторину по географии.","vi":"Tối nay chúng ta sẽ chơi bài kiểm tra địa lý.","fa":"ما امشب در حال انجام یک مسابقه جغرافیا هستیم."},{"de":"Bei dem Quiz im Fernsehen kann man Geld gewinnen.","en":"In the TV quiz you can win money.","ru":"В телевизионной викторине можно выиграть деньги.","vi":"Bạn có thể kiếm được tiền bằng cách làm bài kiểm tra trên TV.","fa":"با شرکت در مسابقه تلویزیونی می توانید برنده شوید."}]},{"word":"die Quizshow","en":"quiz show","ru":"телевикторина","vi":"chương trình đố vui","fa":"نمایش مسابقه","examples":[{"de":"Am Samstagabend schauen wir oft eine Quizshow.","en":"On Saturday evenings we often watch a quiz show.","ru":"По субботним вечерам мы часто смотрим телевикторину.","vi":"Vào tối thứ Bảy, chúng tôi thường xem chương trình đố vui.","fa":"عصرهای شنبه اغلب یک برنامه مسابقه تماشا می کنیم."},{"de":"In der Quizshow kann man viel Geld gewinnen.","en":"On the quiz show you can win a lot of money.","ru":"В телевикторине можно выиграть много денег.","vi":"Bạn có thể giành được rất nhiều tiền trong chương trình đố vui.","fa":"شما می توانید پول زیادی را در نمایش مسابقه برنده شوید."},{"de":"Sie hat sich für eine Quizshow im Fernsehen beworben.","en":"She applied to take part in a quiz show on television.","ru":"Она подала заявку на участие в телевикторине.","vi":"Cô ấy đã đăng ký tham gia một chương trình đố vui trên truyền hình.","fa":"او برای یک برنامه مسابقه تلویزیونی درخواست داد."}]},{"word":"der Quotient","en":"quotient (result of division)","ru":"частное (результат деления)","vi":"thương số","fa":"ضریب","examples":[{"de":"Der Quotient aus zwölf und drei ist vier.","en":"The quotient of twelve and three is four.","ru":"Частное от деления двенадцати на три равно четырём.","vi":"Thương của mười hai và ba là bốn.","fa":"ضریب دوازده و سه چهار است."},{"de":"Wenn man teilt, erhält man einen Quotienten.","en":"When you divide, you get a quotient.","ru":"При делении получают частное.","vi":"Khi bạn chia, bạn nhận được một thương số.","fa":"وقتی تقسیم می کنید یک ضریب بدست می آورید."},{"de":"Der Quotient ist kleiner als eins, wenn der Zähler kleiner als der Nenner ist.","en":"The quotient is less than one if the numerator is smaller than the denominator.","ru":"Частное меньше единицы, если числитель меньше знаменателя.","vi":"Thương số nhỏ hơn một nếu tử số nhỏ hơn mẫu số.","fa":"اگر صورت از مخرج کوچکتر باشد، ضریب کوچکتر از یک است."}]},{"word":"der Rabatt","en":"discount","ru":"скидка","vi":"giảm giá","fa":"تخفیف","examples":[{"de":"Auf Schuhe gibt es diese Woche zwanzig Prozent Rabatt.","en":"This week there is a twenty percent discount on shoes.","ru":"На этой неделе на обувь скидка двадцать процентов.","vi":"Tuần này có đợt giảm giá 20% cho giày.","fa":"در این هفته کفش بیست درصد تخفیف داده شده است."},{"de":"Studenten bekommen in diesem Kino einen Rabatt.","en":"Students get a discount at this cinema.","ru":"Студенты получают скидку в этом кинотеатре.","vi":"Sinh viên được giảm giá tại rạp chiếu phim này.","fa":"دانشجویان در این سینما از تخفیف برخوردار می شوند."}]},{"word":"das Rad","en":"wheel; bicycle","ru":"колесо; велосипед","vi":"bánh xe","fa":"چرخ","examples":[{"de":"Das Rad meines Fahrrads ist kaputt.","en":"The wheel of my bicycle is broken.","ru":"Колесо моего велосипеда сломано.","vi":"Bánh xe đạp của tôi bị hỏng.","fa":"چرخ دوچرخه ام خراب است."},{"de":"Ich fahre jeden Tag mit dem Rad zur Arbeit.","en":"I ride my bike to work every day.","ru":"Каждый день я езжу на велосипеде на работу.","vi":"Tôi đạp xe đi làm hàng ngày.","fa":"من هر روز با دوچرخه به سر کار می روم."}]},{"word":"der Radfahrer","en":"cyclist (male)","ru":"велосипедист (мужчина)","vi":"người đi xe đạp","fa":"دوچرخه سوار","examples":[{"de":"Der Radfahrer musste an der Ampel anhalten.","en":"The cyclist had to stop at the traffic light.","ru":"Велосипедисту пришлось остановиться на светофоре.","vi":"Người đi xe đạp phải dừng lại trước đèn giao thông.","fa":"دوچرخه سوار مجبور شد پشت چراغ راهنمایی توقف کند."},{"de":"Auf diesem Weg sind nur Radfahrer erlaubt.","en":"Only cyclists are allowed on this path.","ru":"По этой дорожке разрешено ездить только велосипедистам.","vi":"Chỉ người đi xe đạp mới được phép đi trên con đường này.","fa":"در این مسیر فقط دوچرخه سواران مجاز هستند."},{"de":"Ein Radfahrer wurde gestern leicht verletzt.","en":"A cyclist was slightly injured yesterday.","ru":"Вчера один велосипедист слегка пострадал.","vi":"Hôm qua một người đi xe đạp bị thương nhẹ.","fa":"دیروز یک دوچرخه سوار به طور جزئی مجروح شد."}]},{"word":"die Radfahrerin","en":"cyclist (female)","ru":"велосипедистка (женщина)","vi":"chết Radfahrerin","fa":"دوچرخه سوار","examples":[{"de":"Die Radfahrerin fuhr ganz langsam den Berg hinauf.","en":"The cyclist rode very slowly up the hill.","ru":"Велосипедистка очень медленно ехала в гору.","vi":"Người đi xe đạp lái xe rất chậm lên núi.","fa":"دوچرخه سوار خیلی آهسته از کوه بالا رفت."},{"de":"Eine Radfahrerin hat mir den Weg gezeigt.","en":"A cyclist showed me the way.","ru":"Одна велосипедистка показала мне дорогу.","vi":"Một người đi xe đạp đã chỉ đường cho tôi.","fa":"دوچرخه سواری راه را به من نشان داد."},{"de":"Die Radfahrerin trägt eine gelbe Warnweste.","en":"The cyclist is wearing a yellow high-visibility vest.","ru":"Велосипедистка в жёлтом светоотражающем жилете.","vi":"Người đi xe đạp mặc áo bảo hộ màu vàng.","fa":"دوچرخه سوار جلیقه ایمنی زرد رنگ به تن دارد."}]},{"word":"das Radio","en":"radio","ru":"радио","vi":"đài phát thanh","fa":"رادیو","examples":[{"de":"Am Morgen höre ich immer Radio.","en":"In the morning I always listen to the radio.","ru":"По утрам я всегда слушаю радио.","vi":"Tôi luôn nghe radio vào buổi sáng.","fa":"من همیشه صبح ها به رادیو گوش می دهم."},{"de":"Im Radio kommt gerade meine Lieblingsmusik.","en":"My favorite music is playing on the radio right now.","ru":"Сейчас по радио звучит моя любимая музыка.","vi":"Bản nhạc yêu thích của tôi hiện đang có trên đài phát thanh.","fa":"موسیقی مورد علاقه من در حال حاضر در رادیو پخش می شود."}]},{"word":"der Radius","en":"radius","ru":"радиус","vi":"bán kính","fa":"شعاع","examples":[{"de":"Der Radius ist halb so lang wie der Durchmesser.","en":"The radius is half as long as the diameter.","ru":"Радиус вдвое короче диаметра.","vi":"Bán kính bằng một nửa chiều dài đường kính.","fa":"شعاع نصف طول قطر است."},{"de":"Um die Fläche zu berechnen, braucht man den Radius.","en":"To calculate the area you need the radius.","ru":"Чтобы вычислить площадь, нужен радиус.","vi":"Để tính diện tích bạn cần bán kính.","fa":"برای محاسبه مساحت به شعاع نیاز دارید."},{"de":"Der Radius dieses Kreises beträgt fünf Zentimeter.","en":"The radius of this circle is five centimetres.","ru":"Радиус этой окружности составляет пять сантиметров.","vi":"Bán kính của vòng tròn này là năm cm.","fa":"شعاع این دایره پنج سانتی متر است."}]},{"word":"der Rahm","en":"cream (especially in southern German/Austrian/Swiss usage)","ru":"сливки (преимущественно в южнонемецком/австрийском/швейцарском употреблении)","vi":"kem","fa":"کرم","examples":[{"de":"Für die Soße brauchen wir noch etwas Rahm.","en":"We still need some cream for the sauce.","ru":"Нам ещё нужно немного сливок для соуса.","vi":"Chúng ta cần thêm kem cho nước sốt.","fa":"برای سس به مقداری خامه دیگر نیاز داریم."},{"de":"Sie schlägt den Rahm steif für den Kuchen.","en":"She is whipping the cream stiff for the cake.","ru":"Она взбивает сливки для торта до крепкой пены.","vi":"Cô đánh kem cho đến khi cứng bánh.","fa":"او خامه را می‌کوبد تا برای کیک سفت شود."},{"de":"In der Schweiz sagt man oft Rahm statt Sahne.","en":"In Switzerland people often say Rahm instead of Sahne for cream.","ru":"В Швейцарии сливки часто называют Rahm, а не Sahne.","vi":"Ở Thụy Sĩ người ta thường nói kem thay vì kem.","fa":"در سوئیس اغلب به جای خامه خامه می گویند."}]},{"word":"der Rand","en":"edge, border","ru":"край, граница","vi":"rìa","fa":"لبه","examples":[{"de":"Das Haus steht am Rand der Stadt.","en":"The house stands at the edge of the city.","ru":"Дом стоит на окраине города.","vi":"Ngôi nhà nằm ở ngoại ô thành phố.","fa":"خانه در حومه شهر است."},{"de":"Schreib die Notiz an den Rand des Blattes.","en":"Write the note in the margin of the page.","ru":"Напиши заметку на полях листа.","vi":"Viết ghi chú vào mép giấy.","fa":"یادداشت را در لبه کاغذ بنویسید."}]},{"word":"der Rasen","en":"lawn","ru":"газон","vi":"bãi cỏ","fa":"چمنزار","examples":[{"de":"Er mäht jeden Samstag den Rasen.","en":"He mows the lawn every Saturday.","ru":"Он подстригает газон каждую субботу.","vi":"Anh ấy cắt cỏ vào thứ Bảy hàng tuần.","fa":"او هر شنبه چمن را می کند."},{"de":"Auf dem Rasen liegen die Kinder in der Sonne.","en":"The children are lying on the lawn in the sun.","ru":"Дети лежат на газоне на солнце.","vi":"Bọn trẻ nằm phơi nắng trên bãi cỏ.","fa":"بچه ها روی چمن زیر آفتاب دراز می کشند."}]},{"word":"rasieren","en":"to shave","ru":"бриться, брить","vi":"cạo râu","fa":"تراشیدن","examples":[{"de":"Er rasiert sich jeden Morgen.","en":"He shaves every morning.","ru":"Он бреется каждое утро.","vi":"Anh ấy cạo râu vào mỗi buổi sáng.","fa":"او هر روز صبح اصلاح می کند."},{"de":"Ich habe mir den Bart rasiert.","en":"I shaved off my beard.","ru":"Я сбрил бороду.","vi":"Tôi đã cạo râu.","fa":"ریشم را تراشیدم."},{"de":"Hast du dich heute rasiert?","en":"Did you shave today?","ru":"Ты сегодня брился?","vi":"Hôm nay bạn đã cạo râu chưa?","fa":"امروز اصلاح کردی؟"}]},{"word":"der Rat","en":"advice; counsel; (also) council","ru":"совет; (также) совет (орган управления)","vi":"hội đồng","fa":"شورا","examples":[{"de":"Kannst du mir einen guten Rat geben?","en":"Can you give me some good advice?","ru":"Можешь дать мне хороший совет?","vi":"Bạn có thể cho tôi một lời khuyên tốt?","fa":"میشه یه راهنمایی خوب به من بکنید؟"},{"de":"Ich habe den Rat meiner Mutter befolgt.","en":"I followed my mother's advice.","ru":"Я последовал совету матери.","vi":"Tôi làm theo lời khuyên của mẹ tôi.","fa":"به توصیه مادرم عمل کردم."},{"de":"In dieser Lage weiß ich keinen Rat.","en":"In this situation I am at a loss for what to do.","ru":"В этой ситуации я в растерянности и не знаю, что делать.","vi":"Trong tình huống này tôi không có lời khuyên nào cả.","fa":"در این شرایط من توصیه ای ندارم."}]},{"word":"die Rate","en":"instalment","ru":"взнос, платёж в рассрочку","vi":"tỷ lệ","fa":"نرخ","examples":[{"de":"Das Sofa bezahlen wir in zwölf Raten.","en":"We are paying for the sofa in twelve instalments.","ru":"Диван мы оплачиваем в двенадцать взносов.","vi":"Chúng tôi trả tiền cho chiếc ghế sofa thành mười hai đợt.","fa":"هزینه مبل را در دوازده قسط پرداخت می کنیم."},{"de":"Die erste Rate ist nächsten Monat fällig.","en":"The first instalment is due next month.","ru":"Первый взнос нужно внести в следующем месяце.","vi":"Đợt đầu tiên sẽ đến hạn vào tháng tới.","fa":"اولین قسط در ماه آینده موعد می شود."},{"de":"Er kann die Raten für den Kredit kaum noch zahlen.","en":"He can hardly pay the instalments on the loan anymore.","ru":"Он едва может выплачивать взносы по кредиту.","vi":"Anh ta hầu như không thể trả các khoản vay.","fa":"او به سختی می تواند اقساط وام را پرداخت کند."}]},{"word":"raten","en":"to guess; to advise","ru":"угадывать; советовать","vi":"khuyên nhủ","fa":"نصیحت کردن","examples":[{"de":"Rate mal, wer heute zu Besuch kommt!","en":"Guess who is coming to visit today!","ru":"Угадай, кто сегодня придёт в гости!","vi":"Đoán xem hôm nay ai sẽ đến thăm nào!","fa":"حدس بزنید چه کسی امروز برای بازدید می آید!"},{"de":"Der Arzt riet ihr, mehr Sport zu treiben.","en":"The doctor advised her to do more sport.","ru":"Врач посоветовал ей больше заниматься спортом.","vi":"Bác sĩ khuyên cô nên tập thể dục nhiều hơn.","fa":"دکتر به او توصیه کرد بیشتر ورزش کند."}]},{"word":"die Ratenzahlung","en":"payment by instalments","ru":"оплата в рассрочку","vi":"thanh toán trả góp","fa":"پرداخت اقساطی","examples":[{"de":"Wir haben den Fernseher per Ratenzahlung gekauft.","en":"We bought the television by instalments.","ru":"Мы купили телевизор в рассрочку.","vi":"Chúng tôi mua trả góp chiếc tivi.","fa":"تلویزیون را قسطی خریدیم."},{"de":"Bei diesem Angebot ist eine Ratenzahlung möglich.","en":"Payment by instalments is possible with this offer.","ru":"По этому предложению возможна оплата в рассрочку.","vi":"Với ưu đãi này, bạn có thể thanh toán theo từng đợt.","fa":"با این پیشنهاد امکان پرداخت اقساطی وجود دارد."},{"de":"Die Ratenzahlung läuft über zwölf Monate.","en":"The instalment payment runs over twelve months.","ru":"Рассрочка рассчитана на двенадцать месяцев.","vi":"Die Ratenzahlung läuft über zwölf Monate.","fa":"پرداخت اقساط بیش از دوازده ماه است."}]},{"word":"das Rathaus","en":"town hall, city hall","ru":"ратуша, мэрия","vi":"tòa thị chính","fa":"تالار شهر","examples":[{"de":"Das Rathaus steht mitten auf dem Marktplatz.","en":"The town hall stands in the middle of the market square.","ru":"Ратуша стоит в центре рыночной площади.","vi":"Tòa thị chính nằm giữa quảng trường chợ.","fa":"تالار شهر در وسط میدان بازار است."},{"de":"Wir haben im Rathaus geheiratet.","en":"We got married at the town hall.","ru":"Мы поженились в ратуше.","vi":"Chúng tôi kết hôn ở tòa thị chính.","fa":"در شهرداری ازدواج کردیم."}]},{"word":"der Ratschlag","en":"piece of advice; tip","ru":"совет (рекомендация), подсказка","vi":"lời khuyên","fa":"مشاوره","examples":[{"de":"Danke für den guten Ratschlag!","en":"Thank you for the good piece of advice!","ru":"Спасибо за хороший совет!","vi":"Cảm ơn vì lời khuyên tốt!","fa":"با تشکر از توصیه خوب!"},{"de":"Mein Großvater gibt mir oft kluge Ratschläge.","en":"My grandfather often gives me wise advice.","ru":"Мой дедушка часто даёт мне мудрые советы.","vi":"My grandfather often gives me wise advice.","fa":"پدربزرگم اغلب نصیحت های عاقلانه ای به من می کند."},{"de":"Sie hat seinen Ratschlag nicht ernst genommen.","en":"She didn't take his advice seriously.","ru":"Она не восприняла его совет всерьёз.","vi":"Cô ấy không coi trọng lời khuyên của anh ấy.","fa":"توصیه های او را جدی نگرفت."}]},{"word":"rauchen","en":"to smoke","ru":"курить","vi":"khói","fa":"دود","examples":[{"de":"Hier darf man nicht rauchen.","en":"You are not allowed to smoke here.","ru":"Здесь нельзя курить.","vi":"Bạn không được phép hút thuốc ở đây.","fa":"اینجا اجازه سیگار کشیدن ندارید."},{"de":"Er hat vor einem Jahr mit dem Rauchen aufgehört.","en":"He quit smoking a year ago.","ru":"Он бросил курить год назад.","vi":"Anh ấy đã ngừng hút thuốc cách đây một năm.","fa":"او یک سال پیش سیگار را ترک کرد."}]},{"word":"der Raucher","en":"smoker (male)","ru":"курильщик (мужчина)","vi":"người hút thuốc","fa":"سیگاری","examples":[{"de":"Mein Onkel ist ein starker Raucher.","en":"My uncle is a heavy smoker.","ru":"Мой дядя заядлый курильщик.","vi":"Chú tôi là người nghiện thuốc lá nặng.","fa":"دایی من سیگاری شدید است."},{"de":"Im Restaurant gibt es keinen Bereich für Raucher.","en":"There is no area for smokers in the restaurant.","ru":"В ресторане нет зоны для курильщиков.","vi":"Không có khu vực hút thuốc trong nhà hàng.","fa":"فضایی برای سیگار کشیدن در رستوران وجود ندارد."},{"de":"Als Raucher sollte man besonders auf seine Gesundheit achten.","en":"As a smoker you should take particular care of your health.","ru":"Как курильщик, ты должен особенно заботиться о здоровье.","vi":"Là người hút thuốc, bạn nên đặc biệt chú ý đến sức khỏe của mình.","fa":"به عنوان یک فرد سیگاری باید به سلامت خود توجه ویژه ای داشته باشید."}]},{"word":"die Raucherin","en":"smoker (female)","ru":"курильщица (женщина)","vi":"người hút thuốc","fa":"سیگاری","examples":[{"de":"Meine Nachbarin ist seit zwanzig Jahren Raucherin.","en":"My neighbour has been a smoker for twenty years.","ru":"Моя соседка курит уже двадцать лет.","vi":"Hàng xóm của tôi đã hút thuốc được hai mươi năm.","fa":"همسایه من بیست سال است که سیگار می کشد."},{"de":"Die Raucherin stand allein auf dem Balkon.","en":"The smoker stood alone on the balcony.","ru":"Курильщица стояла на балконе одна.","vi":"Người hút thuốc đứng một mình trên ban công.","fa":"سیگاری به تنهایی روی بالکن ایستاده بود."},{"de":"Als Raucherin hatte sie oft Husten.","en":"As a smoker she often had a cough.","ru":"Как курильщица, она часто кашляла.","vi":"Là người hút thuốc nên cô thường xuyên bị ho.","fa":"به عنوان یک سیگاری، او اغلب سرفه داشت."}]},{"word":"rauf","en":"up (colloquial, up here/there)","ru":"наверх (разг.)","vi":"lên","fa":"بالا","examples":[{"de":"Komm rauf, das Essen ist fertig!","en":"Come up, the food is ready!","ru":"Поднимайся наверх, еда готова!","vi":"Mau lên, đồ ăn đã sẵn sàng rồi!","fa":"بیا بالا، غذا آماده است!"},{"de":"Wir gehen den Berg rauf.","en":"We are going up the mountain.","ru":"Мы идём в гору.","vi":"Chúng tôi đi lên núi.","fa":"از کوه بالا می رویم."}]},{"word":"rauf-","en":"up- (separable verb prefix, colloquial)","ru":"вверх, наверх (отделяемая приставка, разг.)","vi":"lên-","fa":"بالا-","examples":[{"de":"Kannst du die Tasche raufbringen?","en":"Can you bring the bag up?","ru":"Можешь принести сумку наверх?","vi":"Bạn có thể mang túi lên được không?","fa":"آیا می توانید کیف را بالا بیاورید؟"},{"de":"Wir sind die Treppe raufgegangen.","en":"We went up the stairs.","ru":"Мы поднялись по лестнице.","vi":"Chúng tôi đi lên cầu thang.","fa":"از پله ها بالا رفتیم."},{"de":"Bitte hilf mir, das Sofa raufzutragen.","en":"Please help me carry the sofa up.","ru":"Пожалуйста, помоги мне занести диван наверх.","vi":"Hãy giúp tôi mang ghế sofa lên.","fa":"لطفا به من کمک کنید تا مبل را بالا ببرم."}]},{"word":"der Raum","en":"room, space","ru":"помещение, пространство","vi":"căn phòng","fa":"اتاق","examples":[{"de":"Der Raum ist zu klein für so viele Leute.","en":"The room is too small for so many people.","ru":"Помещение слишком маленькое для стольких людей.","vi":"Căn phòng quá nhỏ cho rất nhiều người.","fa":"اتاق برای این همه آدم خیلی کوچک است."},{"de":"Im Weltraum gibt es keine Luft.","en":"There is no air in space.","ru":"В космосе нет воздуха.","vi":"Không có không khí trong không gian.","fa":"هوا در فضا وجود ندارد."}]},{"word":"raus","en":"out (colloquial)","ru":"наружу, вон (разг.)","vi":"ra ngoài","fa":"بیرون","examples":[{"de":"Geh bitte raus und spiel im Garten.","en":"Please go outside and play in the garden.","ru":"Пожалуйста, иди на улицу и играй в саду.","vi":"Hãy ra ngoài và chơi trong vườn.","fa":"لطفا بیرون بروید و در باغ بازی کنید."},{"de":"Der Hund will raus.","en":"The dog wants to go out.","ru":"Собака хочет выйти на улицу.","vi":"Con chó muốn đi ra ngoài.","fa":"سگ می خواهد برود بیرون."}]},{"word":"raus-","en":"out- (separable verb prefix, colloquial)","ru":"наружу (отделяемая приставка, разг.)","vi":"ra-","fa":"خارج از-","examples":[{"de":"Bring bitte den Müll raus.","en":"Please take the rubbish out.","ru":"Пожалуйста, вынеси мусор.","vi":"Hãy vứt rác đi.","fa":"لطفا سطل زباله را بردارید"},{"de":"Er ist aus dem Haus rausgegangen.","en":"He went out of the house.","ru":"Он вышел из дома.","vi":"Anh ấy đi ra khỏi nhà.","fa":"از خانه بیرون رفت."},{"de":"Kannst du die Katze rauslassen?","en":"Can you let the cat out?","ru":"Можешь выпустить кошку?","vi":"Bạn có thể thả con mèo ra ngoài được không?","fa":"آیا می توانید گربه را رها کنید؟"}]},{"word":"reagieren","en":"to react, to respond","ru":"реагировать, откликаться","vi":"phản ứng","fa":"واکنش نشان دهند","examples":[{"de":"Wie hat sie auf die Nachricht reagiert?","en":"How did she react to the news?","ru":"Как она отреагировала на новость?","vi":"Cô ấy phản ứng thế nào trước tin tức này?","fa":"واکنش او به این خبر چگونه بود؟"},{"de":"Er reagiert immer sehr ruhig.","en":"He always reacts very calmly.","ru":"Он всегда реагирует очень спокойно.","vi":"Anh ấy luôn phản ứng rất bình tĩnh.","fa":"او همیشه بسیار آرام واکنش نشان می دهد."},{"de":"Du musst schnell reagieren.","en":"You have to react quickly.","ru":"Нужно реагировать быстро.","vi":"Bạn phải phản ứng nhanh chóng.","fa":"باید سریع عکس العمل نشان داد."}]},{"word":"die Reaktion","en":"reaction; response","ru":"реакция","vi":"phản ứng","fa":"واکنش","examples":[{"de":"Seine Reaktion auf die Nachricht war sehr ruhig.","en":"His reaction to the news was very calm.","ru":"Его реакция на новость была очень спокойной.","vi":"Phản ứng của anh ấy trước tin này rất bình tĩnh.","fa":"واکنش او به این خبر بسیار آرام بود."},{"de":"Ich hatte mit einer anderen Reaktion gerechnet.","en":"I had expected a different reaction.","ru":"Я ожидал другой реакции.","vi":"Tôi mong đợi một phản ứng khác.","fa":"انتظار واکنش متفاوتی را داشتم."},{"de":"Die schnelle Reaktion des Fahrers verhinderte einen Unfall.","en":"The driver's quick reaction prevented an accident.","ru":"Быстрая реакция водителя предотвратила аварию.","vi":"Phản ứng nhanh chóng của tài xế đã ngăn chặn được tai nạn.","fa":"واکنش سریع راننده از تصادف جلوگیری کرد."}]},{"word":"realisieren","en":"to realize, to carry out","ru":"реализовывать, осуществлять","vi":"nhận ra","fa":"متوجه شدن","examples":[{"de":"Wir wollen unsere Idee bald realisieren.","en":"We want to realize our idea soon.","ru":"Мы хотим скоро реализовать нашу идею.","vi":"Chúng tôi muốn sớm hiện thực hóa ý tưởng của mình.","fa":"ما می خواهیم به زودی ایده خود را محقق کنیم."},{"de":"Das Projekt konnte leider nicht realisiert werden.","en":"Unfortunately the project could not be realized.","ru":"К сожалению, проект не удалось реализовать.","vi":"Thật không may, dự án không thể thực hiện được.","fa":"متاسفانه پروژه محقق نشد."}]},{"word":"realistisch","en":"realistic","ru":"реалистичный","vi":"thực tế","fa":"واقع بینانه","examples":[{"de":"Sei realistisch, das schaffst du nicht in einer Stunde.","en":"Be realistic, you won't manage that in an hour.","ru":"Будь реалистом, за час ты этого не успеешь.","vi":"Hãy thực tế, bạn không thể làm điều này trong một giờ.","fa":"واقع بین باشید، شما نمی توانید این کار را در یک ساعت انجام دهید."},{"de":"Das ist kein realistisches Ziel.","en":"That's not a realistic goal.","ru":"Это не реалистичная цель.","vi":"Đó không phải là một mục tiêu thực tế.","fa":"این یک هدف واقع بینانه نیست."},{"de":"Wir brauchen einen realistischen Plan.","en":"We need a realistic plan.","ru":"Нам нужен реалистичный план.","vi":"Chúng ta cần một kế hoạch thực tế.","fa":"ما به یک برنامه واقعی نیاز داریم."}]},{"word":"die Realität","en":"reality","ru":"реальность, действительность","vi":"sự thật","fa":"واقعیت","examples":[{"de":"In der Realität ist alles viel schwieriger.","en":"In reality everything is much harder.","ru":"В реальности всё гораздо сложнее.","vi":"Trong thực tế mọi thứ khó khăn hơn nhiều.","fa":"در واقعیت همه چیز بسیار دشوارتر است."},{"de":"Sein Traum wurde endlich Realität.","en":"His dream finally became reality.","ru":"Его мечта наконец стала реальностью.","vi":"Ước mơ của anh cuối cùng đã trở thành hiện thực.","fa":"رویای او سرانجام به واقعیت تبدیل شد."},{"de":"Wir müssen die Realität akzeptieren.","en":"We have to accept reality.","ru":"Нам нужно принять реальность.","vi":"Chúng ta phải chấp nhận thực tế.","fa":"ما باید واقعیت را بپذیریم."}]},{"word":"die Rechenaufgabe","en":"arithmetic problem, sum","ru":"арифметическая задача, пример","vi":"chết Rechenaufgabe","fa":"مشکل محاسبه","examples":[{"de":"Diese Rechenaufgabe ist gar nicht so schwer.","en":"This arithmetic problem is not that difficult.","ru":"Эта задача вовсе не такая сложная.","vi":"Bài toán tính toán này không khó lắm.","fa":"این مشکل محاسبه آنقدرها هم سخت نیست."},{"de":"Der Lehrer stellte eine knifflige Rechenaufgabe.","en":"The teacher set a tricky sum.","ru":"Учитель задал хитрую задачу.","vi":"Giáo viên đặt ra một bài toán khó.","fa":"معلم یک مسئله حسابی پیچیده مطرح کرد."},{"de":"Ich habe die Rechenaufgabe richtig gelöst.","en":"I solved the arithmetic problem correctly.","ru":"Я правильно решил задачу.","vi":"Tôi đã giải được bài toán một cách chính xác.","fa":"من مشکل ریاضی را درست حل کردم."}]},{"word":"die Recherche","en":"research","ru":"исследование, поиск информации","vi":"nghiên cứu","fa":"تحقیق","examples":[{"de":"Für den Artikel machte die Journalistin eine gründliche Recherche.","en":"For the article, the journalist did thorough research.","ru":"Для статьи журналистка провела тщательное исследование.","vi":"Nhà báo đã nghiên cứu kỹ lưỡng cho bài báo.","fa":"روزنامه نگار برای مقاله تحقیقات کاملی انجام داد."},{"de":"Meine Recherche im Internet hat lange gedauert.","en":"My research on the internet took a long time.","ru":"Мой поиск информации в интернете занял много времени.","vi":"Nghiên cứu của tôi trên internet mất một thời gian dài.","fa":"تحقیق من در اینترنت خیلی طول کشید."}]},{"word":"recherchieren","en":"to research, to look up","ru":"искать, разузнавать (информацию)","vi":"nghiên cứu","fa":"تحقیق کنید","examples":[{"de":"Ich muss noch ein paar Fakten recherchieren.","en":"I still need to research a few facts.","ru":"Мне ещё надо разузнать несколько фактов.","vi":"Tôi vẫn cần phải nghiên cứu một vài sự thật.","fa":"من هنوز باید در مورد چند واقعیت تحقیق کنم."},{"de":"Der Journalist recherchiert seit Wochen.","en":"The journalist has been researching for weeks.","ru":"Журналист ведёт расследование уже несколько недель.","vi":"Nhà báo đã nghiên cứu trong nhiều tuần.","fa":"این روزنامه نگار هفته هاست که در حال تحقیق است."},{"de":"Hast du im Internet recherchiert?","en":"Did you research online?","ru":"Ты искал информацию в интернете?","vi":"Bạn đã nghiên cứu trên internet?","fa":"آیا در اینترنت تحقیق کرده اید؟"}]},{"word":"rechnen","en":"to calculate","ru":"считать, вычислять","vi":"tính toán","fa":"محاسبه کنید","examples":[{"de":"Die Kinder lernen in der Schule rechnen.","en":"The children learn to do math at school.","ru":"Дети учатся считать в школе.","vi":"Trẻ em học số học ở trường.","fa":"بچه ها در مدرسه حساب را یاد می گیرند."},{"de":"Ich rechne mit deiner Hilfe morgen.","en":"I am counting on your help tomorrow.","ru":"Я рассчитываю на твою помощь завтра.","vi":"Tôi trông cậy vào sự giúp đỡ của bạn vào ngày mai.","fa":"من فردا روی کمک شما حساب می کنم."}]},{"word":"der Rechner","en":"computer; calculator","ru":"компьютер; калькулятор","vi":"máy tính","fa":"کامپیوتر","examples":[{"de":"Mein Rechner ist heute leider abgestürzt.","en":"Unfortunately my computer crashed today.","ru":"К сожалению, сегодня мой компьютер завис.","vi":"Thật không may, hôm nay máy tính của tôi bị hỏng.","fa":"متاسفانه کامپیوتر من امروز خراب شد."},{"de":"Schalte bitte den Rechner aus, wenn du fertig bist.","en":"Please switch off the computer when you are finished.","ru":"Выключите, пожалуйста, компьютер, когда закончите.","vi":"Vui lòng tắt máy tính khi bạn làm xong.","fa":"لطفاً وقتی کارتان تمام شد کامپیوتر را خاموش کنید."},{"de":"Für diese Aufgabe darfst du keinen Rechner benutzen.","en":"You may not use a calculator for this task.","ru":"Для этого задания нельзя пользоваться калькулятором.","vi":"Bạn không được phép sử dụng máy tính cho nhiệm vụ này.","fa":"شما مجاز به استفاده از رایانه برای این کار نیستید."}]},{"word":"die Rechnung","en":"bill; invoice","ru":"счёт","vi":"hóa đơn","fa":"صورت حساب","examples":[{"de":"Können wir bitte die Rechnung haben?","en":"Could we have the bill, please?","ru":"Можно нам, пожалуйста, счёт?","vi":"Làm ơn cho chúng tôi xin hóa đơn được không?","fa":"آیا می توانیم صورتحساب را داشته باشیم؟"},{"de":"Die Rechnung muss innerhalb von 14 Tagen bezahlt werden.","en":"The invoice must be paid within 14 days.","ru":"Счёт должен быть оплачен в течение 14 дней.","vi":"Hóa đơn phải được thanh toán trong vòng 14 ngày.","fa":"فاکتور باید ظرف 14 روز پرداخت شود."}]},{"word":"die Rechnung bezahlen","en":"to pay the bill","ru":"оплачивать счёт","vi":"thanh toán hóa đơn","fa":"قبض را پرداخت کنید","examples":[{"de":"Können wir bitte die Rechnung bezahlen?","en":"Can we please pay the bill?","ru":"Можно нам, пожалуйста, оплатить счёт?","vi":"Chúng tôi có thể vui lòng thanh toán hóa đơn được không?","fa":"میشه لطفا قبض رو پرداخت کنیم؟"},{"de":"Er hat die Rechnung mit Karte bezahlt.","en":"He paid the bill by card.","ru":"Он оплатил счёт картой.","vi":"Anh ấy thanh toán hóa đơn bằng thẻ.","fa":"قبض را با کارت پرداخت کرد."},{"de":"Wer bezahlt heute die Rechnung?","en":"Who is paying the bill today?","ru":"Кто сегодня платит по счёту?","vi":"Ai sẽ thanh toán hóa đơn ngày hôm nay?","fa":"چه کسی امروز قبض را پرداخت می کند؟"}]},{"word":"der Rechnungsbetrag","en":"invoice amount; total of a bill","ru":"сумма счёта, итоговая сумма к оплате","vi":"số tiền hóa đơn","fa":"مبلغ فاکتور","examples":[{"de":"Bitte überweisen Sie den Rechnungsbetrag bis Ende des Monats.","en":"Please transfer the invoice amount by the end of the month.","ru":"Переведите, пожалуйста, сумму счёта до конца месяца.","vi":"Vui lòng chuyển số tiền hóa đơn vào cuối tháng.","fa":"لطفا مبلغ فاکتور را تا پایان ماه واریز کنید."},{"de":"Der Rechnungsbetrag ist höher als erwartet.","en":"The invoice amount is higher than expected.","ru":"Сумма счёта оказалась выше, чем ожидалось.","vi":"Số tiền hóa đơn cao hơn dự kiến.","fa":"مبلغ فاکتور بیشتر از حد انتظار است."},{"de":"Auf der Rechnung steht der Rechnungsbetrag ganz unten.","en":"The invoice amount is shown at the bottom of the bill.","ru":"Сумма счёта указана внизу.","vi":"Số tiền ghi ở cuối hóa đơn.","fa":"مبلغ فاکتور در پایین فاکتور می باشد."}]},{"word":"das Recht","en":"right; law","ru":"право","vi":"bên phải","fa":"حق","examples":[{"de":"Jeder Mensch hat das Recht auf Bildung.","en":"Every person has the right to education.","ru":"Каждый человек имеет право на образование.","vi":"Mọi người đều có quyền được giáo dục.","fa":"هر فرد حق تحصیل دارد."},{"de":"Er studiert Recht an der Universität.","en":"He studies law at the university.","ru":"Он изучает право в университете.","vi":"Anh ấy học luật ở trường đại học.","fa":"او در دانشگاه حقوق می خواند."}]},{"word":"recht","en":"right, correct; quite","ru":"правый, верный; довольно","vi":"đúng","fa":"درست است","examples":[{"de":"Du hast recht, das war ein Fehler.","en":"You are right, that was a mistake.","ru":"Ты прав, это была ошибка.","vi":"Bạn nói đúng, đó là một sai lầm.","fa":"حق با شماست، اشتباه بود"},{"de":"Das Wetter ist heute recht schön.","en":"The weather is quite nice today.","ru":"Погода сегодня довольно хорошая.","vi":"Thời tiết hôm nay khá đẹp.","fa":"امروز هوا خیلی خوبه"}]},{"word":"das Rechteck","en":"rectangle","ru":"прямоугольник","vi":"hình chữ nhật","fa":"مستطیل","examples":[{"de":"Ein Rechteck hat zwei lange und zwei kurze Seiten.","en":"A rectangle has two long and two short sides.","ru":"У прямоугольника две длинные и две короткие стороны.","vi":"Hình chữ nhật có hai cạnh dài và hai cạnh ngắn.","fa":"یک مستطیل دو ضلع بلند و دو ضلع کوتاه دارد."},{"de":"Die Fläche eines Rechtecks ist Länge mal Breite.","en":"The area of a rectangle is length times width.","ru":"Площадь прямоугольника — это длина умножить на ширину.","vi":"Diện tích hình chữ nhật bằng chiều dài nhân chiều rộng.","fa":"مساحت یک مستطیل طول ضربدر عرض است."},{"de":"Ein Quadrat ist ein besonderes Rechteck.","en":"A square is a special kind of rectangle.","ru":"Квадрат — это особый прямоугольник.","vi":"Hình vuông là một hình chữ nhật đặc biệt.","fa":"مربع یک مستطیل خاص است."}]},{"word":"rechtlich","en":"legal, in legal terms","ru":"правовой, юридический, с точки зрения права","vi":"hợp pháp","fa":"به صورت قانونی","examples":[{"de":"Das ist rechtlich nicht erlaubt.","en":"That is not legally allowed.","ru":"Это юридически не разрешено.","vi":"Điều này không được phép về mặt pháp lý.","fa":"این کار از نظر قانونی مجاز نیست."},{"de":"Wir holen uns rechtlichen Rat.","en":"We're getting legal advice.","ru":"Мы получаем юридическую консультацию.","vi":"Chúng tôi nhận được lời khuyên pháp lý.","fa":"مشاوره حقوقی می گیریم"},{"de":"Rechtlich gesehen hast du recht.","en":"Legally speaking, you're right.","ru":"С юридической точки зрения ты прав.","vi":"Về mặt pháp lý, bạn nói đúng.","fa":"از نظر قانونی حق با شماست."}]},{"word":"rechts","en":"on the right, to the right","ru":"справа, направо","vi":"đúng","fa":"درست است","examples":[{"de":"An der Ampel musst du rechts abbiegen.","en":"You have to turn right at the traffic light.","ru":"На светофоре тебе нужно повернуть направо.","vi":"Tại đèn giao thông bạn phải rẽ phải.","fa":"در چراغ راهنمایی باید به راست بپیچید."},{"de":"Das Geschäft liegt rechts neben der Bank.","en":"The shop is to the right of the bank.","ru":"Магазин находится справа от банка.","vi":"Cửa hàng nằm bên phải ngân hàng.","fa":"مغازه در سمت راست بانک است."}]},{"word":"der Rechtsanwalt","en":"lawyer; solicitor (male)","ru":"адвокат, юрист (мужчина)","vi":"luật sư","fa":"وکیل","examples":[{"de":"In diesem Fall solltest du einen Rechtsanwalt fragen.","en":"In this case you should ask a lawyer.","ru":"В этом деле тебе стоит обратиться к адвокату.","vi":"Trong trường hợp này bạn nên hỏi luật sư.","fa":"در این مورد باید از یک وکیل بپرسید."},{"de":"Der Rechtsanwalt vertritt seinen Mandanten vor Gericht.","en":"The lawyer represents his client in court.","ru":"Адвокат представляет своего клиента в суде.","vi":"Luật sư đại diện cho khách hàng của mình tại tòa án.","fa":"وکیل مدافع موکل خود در دادگاه است."},{"de":"Mein Rechtsanwalt hat mir einen guten Rat gegeben.","en":"My lawyer gave me good advice.","ru":"Мой адвокат дал мне хороший совет.","vi":"Luật sư của tôi đã cho tôi lời khuyên tốt.","fa":"وکیلم به من توصیه خوبی کرد."}]},{"word":"die Rechtsschutzversicherung","en":"legal expenses insurance","ru":"страхование судебных расходов (юридической защиты)","vi":"bảo hiểm bảo vệ pháp lý","fa":"بیمه حمایت قانونی","examples":[{"de":"Eine Rechtsschutzversicherung übernimmt oft die Anwaltskosten.","en":"Legal expenses insurance often covers the lawyer's fees.","ru":"Страхование судебных расходов часто покрывает гонорары адвоката.","vi":"Bảo hiểm bảo vệ pháp lý thường bao gồm các chi phí pháp lý.","fa":"بیمه حمایت حقوقی اغلب هزینه های قانونی را پوشش می دهد."},{"de":"Wir haben eine Rechtsschutzversicherung für die Familie abgeschlossen.","en":"We took out legal expenses insurance for the family.","ru":"Мы оформили страхование судебных расходов для семьи.","vi":"Chúng tôi đã mua bảo hiểm bảo vệ pháp lý cho gia đình.","fa":"بیمه حمایت قانونی برای خانواده بسته ایم."},{"de":"Ohne Rechtsschutzversicherung kann ein Prozess sehr teuer werden.","en":"Without legal expenses insurance a court case can become very expensive.","ru":"Без такого страхования судебное дело может обойтись очень дорого.","vi":"Nếu không có bảo hiểm bảo vệ pháp lý, một vụ kiện có thể rất tốn kém.","fa":"بدون بیمه حمایت حقوقی، دعوا می تواند بسیار گران باشد."}]},{"word":"rechtzeitig","en":"on time, in time","ru":"своевременно, вовремя","vi":"đúng lúc","fa":"در زمان","examples":[{"de":"Wir müssen rechtzeitig am Flughafen sein.","en":"We have to be at the airport on time.","ru":"Нам нужно вовремя быть в аэропорту.","vi":"Chúng ta phải có mặt ở sân bay đúng giờ.","fa":"ما باید به موقع در فرودگاه باشیم."},{"de":"Er kam rechtzeitig zur Prüfung.","en":"He arrived on time for the exam.","ru":"Он вовремя пришёл на экзамен.","vi":"Anh ấy đến thi đúng giờ.","fa":"به موقع سر امتحان آمد."}]},{"word":"recyceln","en":"to recycle","ru":"перерабатывать (вторсырьё)","vi":"tái chế","fa":"بازیافت","examples":[{"de":"In unserem Haushalt recyceln wir Papier, Glas und Kunststoff getrennt.","en":"In our household we recycle paper, glass and plastic separately.","ru":"В нашем доме мы перерабатываем бумагу, стекло и пластик раздельно.","vi":"Trong gia đình chúng tôi tái chế giấy, thủy tinh và nhựa riêng biệt.","fa":"در خانه ما کاغذ، شیشه و پلاستیک را جداگانه بازیافت می کنیم."},{"de":"Alte Handys kann man bei vielen Geschäften recyceln lassen.","en":"You can have old mobile phones recycled at many shops.","ru":"Старые телефоны во многих магазинах можно сдать на переработку.","vi":"Điện thoại di động cũ có thể được tái chế ở nhiều cửa hàng.","fa":"تلفن های همراه قدیمی را می توان در بسیاری از فروشگاه ها بازیافت کرد."},{"de":"Aluminium lässt sich nahezu beliebig oft recyceln.","en":"Aluminium can be recycled almost any number of times.","ru":"Алюминий можно перерабатывать практически неограниченное число раз.","vi":"Nhôm có thể được tái chế gần như bất kỳ số lần nào.","fa":"آلومینیوم را می توان تقریباً هر چند بار بازیافت کرد."}]},{"word":"das Recycling","en":"recycling","ru":"переработка (вторичных материалов), ресайклинг","vi":"việc tái chế","fa":"the recycling","examples":[{"de":"Durch Recycling lässt sich aus altem Glas wieder neues Glas herstellen.","en":"Through recycling, new glass can be made again from old glass.","ru":"Благодаря переработке из старого стекла можно снова получить новое стекло.","vi":"Kính mới có thể được làm từ kính cũ thông qua việc tái chế.","fa":"شیشه های جدید را می توان از شیشه های قدیمی از طریق بازیافت ساخت."},{"de":"Recycling spart Energie und schont die Rohstoffe.","en":"Recycling saves energy and protects raw materials.","ru":"Переработка экономит энергию и бережёт сырьё.","vi":"Tái chế tiết kiệm năng lượng và bảo vệ nguyên liệu thô.","fa":"بازیافت باعث صرفه جویی در انرژی و محافظت از مواد خام می شود."},{"de":"Nicht jeder Kunststoff eignet sich für das Recycling.","en":"Not every plastic is suitable for recycling.","ru":"Не всякий пластик подходит для переработки.","vi":"Không phải tất cả nhựa đều phù hợp để tái chế.","fa":"همه پلاستیک ها برای بازیافت مناسب نیستند."}]},{"word":"der Recyclinghof","en":"recycling centre","ru":"пункт приёма вторсырья, центр переработки отходов","vi":"trung tâm tái chế","fa":"مرکز بازیافت","examples":[{"de":"Den alten Schrank bringen wir zum Recyclinghof.","en":"We are taking the old cupboard to the recycling centre.","ru":"Мы везём старый шкаф в пункт приёма вторсырья.","vi":"Chúng tôi mang chiếc tủ cũ đến trung tâm tái chế.","fa":"کمد قدیمی را به مرکز بازیافت می بریم."},{"de":"Der Recyclinghof ist samstags bis vierzehn Uhr geöffnet.","en":"The recycling centre is open until two o'clock on Saturdays.","ru":"По субботам пункт приёма открыт до двух часов.","vi":"Trung tâm tái chế mở cửa đến 2 giờ chiều. vào các ngày thứ Bảy.","fa":"مرکز بازیافت تا ساعت 14 باز است. در روزهای شنبه"},{"de":"Auf dem Recyclinghof kann man Altglas und Elektrogeräte abgeben.","en":"At the recycling centre you can drop off old glass and electrical appliances.","ru":"В пункте приёма можно сдать старое стекло и электроприборы.","vi":"Bạn có thể đem kính và thiết bị điện cũ đến trung tâm tái chế.","fa":"می توانید شیشه های قدیمی و لوازم الکتریکی را در مرکز بازیافت تحویل دهید."}]},{"word":"reden","en":"to talk, to speak","ru":"говорить, разговаривать","vi":"nói chuyện","fa":"صحبت کنید","examples":[{"de":"Wir müssen dringend über das Problem reden.","en":"We urgently need to talk about the problem.","ru":"Нам срочно нужно поговорить о проблеме.","vi":"Chúng tôi cần khẩn trương nói về vấn đề này.","fa":"ما باید فوراً در مورد مشکل صحبت کنیم."},{"de":"Er redet gern über Politik.","en":"He likes to talk about politics.","ru":"Он любит разговаривать о политике.","vi":"Anh ấy thích nói về chính trị.","fa":"او دوست دارد در مورد سیاست صحبت کند."}]},{"word":"reduzieren","en":"to reduce","ru":"снижать, сокращать","vi":"giảm bớt","fa":"کاهش دهد","examples":[{"de":"Der Laden hat die Preise stark reduziert.","en":"The shop reduced the prices significantly.","ru":"Магазин сильно снизил цены.","vi":"Cửa hàng đã giảm giá đáng kể.","fa":"این فروشگاه قیمت ها را به میزان قابل توجهی کاهش داده است."},{"de":"Wir sollten unseren Stress reduzieren.","en":"We should reduce our stress.","ru":"Нам следует сократить свой стресс.","vi":"Chúng ta nên giảm bớt căng thẳng.","fa":"ما باید استرس خود را کاهش دهیم."}]},{"word":"das Referat","en":"presentation, report (oral/written)","ru":"доклад, реферат","vi":"báo cáo","fa":"گزارش","examples":[{"de":"Sie hält morgen ein Referat über Klimawandel.","en":"Tomorrow she is giving a presentation about climate change.","ru":"Завтра она делает доклад об изменении климата.","vi":"Cô ấy sẽ có buổi nói chuyện về biến đổi khí hậu vào ngày mai.","fa":"او فردا در مورد تغییرات آب و هوایی سخنرانی می کند."},{"de":"Ich muss noch mein Referat vorbereiten.","en":"I still have to prepare my presentation.","ru":"Мне ещё нужно подготовить свой доклад.","vi":"Tôi vẫn phải chuẩn bị bài thuyết trình của mình.","fa":"من هنوز باید ارائه خود را آماده کنم."}]},{"word":"die Reform","en":"reform","ru":"реформа","vi":"cải cách","fa":"اصلاحات","examples":[{"de":"Die Regierung plant eine Reform des Bildungssystems.","en":"The government is planning a reform of the education system.","ru":"Правительство планирует реформу системы образования.","vi":"Chính phủ đang lên kế hoạch cải cách hệ thống giáo dục.","fa":"دولت در حال برنامه ریزی برای اصلاح نظام آموزشی است."},{"de":"Die neue Reform wird viel diskutiert.","en":"The new reform is much discussed.","ru":"Новая реформа широко обсуждается.","vi":"Cuộc cải cách mới đang được thảo luận rất nhiều.","fa":"اصلاحات جدید بسیار مورد بحث است."}]},{"word":"das Regal","en":"shelf, shelving unit","ru":"полка, стеллаж","vi":"cái kệ","fa":"قفسه","examples":[{"de":"Die Bücher stehen ordentlich im Regal.","en":"The books are neatly arranged on the shelf.","ru":"Книги аккуратно стоят на полке.","vi":"Sách được xếp gọn gàng trên kệ.","fa":"کتاب ها به طور مرتب روی قفسه هستند."},{"de":"Ich brauche ein neues Regal für die Küche.","en":"I need a new shelf for the kitchen.","ru":"Мне нужна новая полка для кухни.","vi":"Tôi cần một cái kệ mới cho nhà bếp.","fa":"به یک قفسه جدید برای آشپزخانه نیاز دارم."}]},{"word":"die Regel","en":"rule","ru":"правило","vi":"quy tắc","fa":"قانون","examples":[{"de":"In der Schule gibt es viele Regeln, die man beachten muss.","en":"At school there are many rules that you have to follow.","ru":"В школе есть много правил, которые нужно соблюдать.","vi":"Có rất nhiều quy tắc ở trường mà bạn phải tuân theo.","fa":"قوانین زیادی در مدرسه وجود دارد که باید آنها را رعایت کنید."},{"de":"Als Ausnahme von der Regel darf er heute später kommen.","en":"As an exception to the rule, he is allowed to come later today.","ru":"В качестве исключения из правила ему разрешено сегодня прийти позже.","vi":"Như một ngoại lệ đối với quy định, hôm nay anh ấy được phép đến muộn hơn.","fa":"به عنوان یک استثنا از قاعده، او اجازه دارد بعداً امروز بیاید."}]},{"word":"regelmäßig","en":"regular","ru":"регулярный","vi":"thường xuyên","fa":"به طور منظم","examples":[{"de":"Sie geht regelmäßig ins Fitnessstudio.","en":"She goes to the gym regularly.","ru":"Она регулярно ходит в спортзал.","vi":"Cô ấy đến phòng tập thể dục thường xuyên.","fa":"او مرتب به باشگاه می رود."},{"de":"Du solltest regelmäßig Pausen machen.","en":"You should take regular breaks.","ru":"Тебе следует делать регулярные перерывы.","vi":"Bạn nên nghỉ giải lao thường xuyên.","fa":"باید به طور منظم استراحت کنید."},{"de":"Der Bus fährt regelmäßig alle zehn Minuten.","en":"The bus runs regularly every ten minutes.","ru":"Автобус ходит регулярно каждые десять минут.","vi":"Xe buýt chạy đều đặn cứ mười phút một lần.","fa":"اتوبوس به طور منظم هر ده دقیقه یکبار حرکت می کند."}]},{"word":"regelmäßig üben","en":"to practise regularly","ru":"регулярно упражняться, заниматься на постоянной основе","vi":"luyện tập thường xuyên","fa":"به طور منظم تمرین کنید","examples":[{"de":"Wer Fortschritte machen will, muss regelmäßig üben.","en":"Anyone who wants to make progress has to practise regularly.","ru":"Кто хочет добиться прогресса, должен регулярно упражняться.","vi":"Muốn tiến bộ thì phải luyện tập thường xuyên.","fa":"اگر می خواهید پیشرفت کنید، باید به طور منظم تمرین کنید."},{"de":"Es ist besser, kurz und regelmäßig zu üben als selten und lange.","en":"It is better to practise briefly and regularly than rarely and at length.","ru":"Лучше упражняться понемногу и регулярно, чем редко и подолгу.","vi":"Sẽ tốt hơn nếu thực hành trong thời gian ngắn và thường xuyên hơn là hiếm khi và trong thời gian dài.","fa":"بهتر است به طور مختصر و منظم تمرین کنید تا به ندرت و برای مدت طولانی."},{"de":"Sie versucht, dreimal pro Woche regelmäßig zu üben.","en":"She tries to practise regularly three times a week.","ru":"Она старается регулярно заниматься три раза в неделю.","vi":"Cô cố gắng tập luyện đều đặn ba lần một tuần.","fa":"او سعی می کند به طور منظم سه بار در هفته تمرین کند."}]},{"word":"regeln","en":"to regulate; to settle/arrange","ru":"регулировать; улаживать","vi":"điều tiết","fa":"تنظیم کند","examples":[{"de":"Der Verkehr wird an dieser Kreuzung von einer Ampel geregelt.","en":"Traffic at this intersection is regulated by a traffic light.","ru":"Движение на этом перекрёстке регулируется светофором.","vi":"Giao thông tại ngã tư này được điều khiển bởi đèn giao thông.","fa":"ترافیک در این تقاطع توسط چراغ راهنمایی کنترل می شود."},{"de":"Wir müssen die Details noch vor der Reise regeln.","en":"We still need to settle the details before the trip.","ru":"Нам ещё нужно уладить детали перед поездкой.","vi":"Chúng tôi phải sắp xếp các chi tiết trước chuyến đi.","fa":"قبل از سفر باید جزئیات را مرتب کنیم."}]},{"word":"der Regenwald","en":"rainforest","ru":"тропический лес, дождевой лес","vi":"rừng nhiệt đới","fa":"جنگل بارانی","examples":[{"de":"Der Regenwald ist die Heimat von Millionen Tier- und Pflanzenarten.","en":"The rainforest is home to millions of animal and plant species.","ru":"Тропический лес — родина миллионов видов животных и растений.","vi":"Rừng nhiệt đới là nơi sinh sống của hàng triệu loài động vật và thực vật.","fa":"جنگل های بارانی زیستگاه میلیون ها گونه جانوری و گیاهی است."},{"de":"Der tropische Regenwald produziert einen großen Teil unseres Sauerstoffs.","en":"The tropical rainforest produces a large part of our oxygen.","ru":"Тропический дождевой лес производит большую часть нашего кислорода.","vi":"Rừng mưa nhiệt đới tạo ra phần lớn oxy cho chúng ta.","fa":"جنگل های بارانی استوایی بیشتر اکسیژن ما را تولید می کند."},{"de":"Jedes Jahr verschwindet ein Stück Regenwald für die Landwirtschaft.","en":"Every year a piece of rainforest disappears for agriculture.","ru":"Каждый год кусок тропического леса исчезает ради сельского хозяйства.","vi":"Mỗi năm một mảnh rừng nhiệt đới biến mất để phục vụ nông nghiệp.","fa":"هر سال یک قطعه از جنگل های بارانی برای کشاورزی ناپدید می شود."}]},{"word":"die Regierung","en":"government","ru":"правительство","vi":"chính phủ","fa":"دولت","examples":[{"de":"Die Regierung hat ein neues Gesetz beschlossen.","en":"The government has passed a new law.","ru":"Правительство приняло новый закон.","vi":"Chính phủ đã thông qua một luật mới.","fa":"دولت قانون جدیدی تصویب کرده است."},{"de":"Viele Bürger sind mit der Regierung unzufrieden.","en":"Many citizens are dissatisfied with the government.","ru":"Многие граждане недовольны правительством.","vi":"Nhiều người dân không hài lòng với chính phủ.","fa":"بسیاری از شهروندان از دولت ناراضی هستند."}]},{"word":"die Region","en":"region","ru":"регион","vi":"khu vực","fa":"منطقه","examples":[{"de":"In dieser Region gibt es viele Weinberge.","en":"There are many vineyards in this region.","ru":"В этом регионе много виноградников.","vi":"Có rất nhiều vườn nho ở vùng này.","fa":"در این منطقه تاکستان های زیادی وجود دارد."},{"de":"Das Klima ist von Region zu Region sehr unterschiedlich.","en":"The climate varies greatly from region to region.","ru":"Климат сильно отличается от региона к региону.","vi":"Khí hậu thay đổi rất nhiều từ vùng này sang vùng khác.","fa":"آب و هوا از منطقه ای به منطقه دیگر بسیار متفاوت است."}]},{"word":"regional","en":"regional, local","ru":"региональный, местный","vi":"khu vực","fa":"منطقه ای","examples":[{"de":"Ich kaufe gern regionale Produkte.","en":"I like buying regional products.","ru":"Я люблю покупать местные продукты.","vi":"Tôi thích mua sản phẩm của vùng.","fa":"من خرید محصولات منطقه ای را دوست دارم."},{"de":"Auf dem Markt gibt es viel regionales Gemüse.","en":"There's a lot of locally grown vegetables at the market.","ru":"На рынке много овощей местного выращивания.","vi":"Có rất nhiều loại rau địa phương trên thị trường.","fa":"سبزیجات منطقه ای زیادی در بازار وجود دارد."},{"de":"Es gibt große regionale Unterschiede beim Wetter.","en":"There are big regional differences in the weather.","ru":"В погоде есть большие региональные различия.","vi":"Có sự khác biệt lớn giữa các vùng về thời tiết.","fa":"تفاوت های منطقه ای زیادی در آب و هوا وجود دارد."}]},{"word":"regnen","en":"to rain","ru":"идти (о дожде)","vi":"mưa","fa":"باران","examples":[{"de":"Draußen regnet es seit dem Morgen.","en":"It has been raining outside since morning.","ru":"На улице идёт дождь с самого утра.","vi":"Ngoài trời đang mưa từ sáng.","fa":"از صبح بیرون باران می بارد."},{"de":"Nimm einen Schirm mit, es soll heute regnen.","en":"Take an umbrella with you, it's supposed to rain today.","ru":"Возьми с собой зонт, сегодня обещают дождь.","vi":"Hãy mang ô theo nhé, hôm nay trời sẽ mưa.","fa":"یه چتر با خودت ببر، قراره امروز بارون بباره."}]},{"word":"reich","en":"rich","ru":"богатый","vi":"giàu có","fa":"ثروتمند","examples":[{"de":"Seine Familie ist sehr reich.","en":"His family is very rich.","ru":"Его семья очень богатая.","vi":"Gia đình anh ấy rất giàu có.","fa":"خانواده او بسیار ثروتمند هستند."},{"de":"Das Land ist reich an Bodenschätzen.","en":"The country is rich in natural resources.","ru":"Страна богата полезными ископаемыми.","vi":"Đất nước này rất giàu tài nguyên khoáng sản.","fa":"این کشور از نظر منابع معدنی غنی است."}]},{"word":"reichen","en":"to be enough; to hand/pass","ru":"хватать; подавать/протягивать","vi":"đủ rồi","fa":"به اندازه کافی","examples":[{"de":"Das Geld reicht nicht für ein neues Auto.","en":"The money isn't enough for a new car.","ru":"Денег не хватает на новую машину.","vi":"Không có đủ tiền để mua một chiếc xe mới.","fa":"پول کافی برای یک ماشین جدید وجود ندارد."},{"de":"Kannst du mir bitte das Salz reichen?","en":"Can you pass me the salt, please?","ru":"Можешь передать мне соль, пожалуйста?","vi":"Bạn có thể vui lòng đưa cho tôi muối được không?","fa":"میشه لطفا نمک را به من بدهید؟"}]},{"word":"reif","en":"ripe; mature","ru":"спелый; зрелый","vi":"chín muồi","fa":"رسیده","examples":[{"de":"Die Bananen sind noch nicht reif.","en":"The bananas are not ripe yet.","ru":"Бананы ещё не спелые.","vi":"Chuối vẫn chưa chín.","fa":"موز هنوز نرسیده است."},{"de":"Er ist für sein Alter schon sehr reif.","en":"He is already very mature for his age.","ru":"Он уже очень зрелый для своего возраста.","vi":"Anh ấy rất trưởng thành so với tuổi của mình.","fa":"او نسبت به سن خود بسیار بالغ است."}]},{"word":"der Reifen","en":"tire","ru":"шина","vi":"lốp xe","fa":"لاستیک","examples":[{"de":"Im Winter braucht man andere Reifen.","en":"In winter you need different tires.","ru":"Зимой нужны другие шины.","vi":"Vào mùa đông, bạn cần những loại lốp khác nhau.","fa":"در زمستان به لاستیک های مختلفی نیاز دارید."},{"de":"Der Reifen ist platt, wir müssen ihn wechseln.","en":"The tire is flat, we have to change it.","ru":"Шина спущена, нам нужно её поменять.","vi":"Lốp bị xẹp, chúng ta phải thay nó.","fa":"لاستیک پنچر شده باید عوضش کنیم"}]},{"word":"die Reihe","en":"row; series","ru":"ряд; серия","vi":"hàng","fa":"ردیف","examples":[{"de":"Wir sitzen in der ersten Reihe im Kino.","en":"We are sitting in the first row at the cinema.","ru":"Мы сидим в первом ряду в кино.","vi":"Chúng tôi đang ngồi ở hàng ghế đầu của rạp chiếu phim.","fa":"ما در ردیف اول سینما نشسته ایم."},{"de":"Er ist jetzt an der Reihe.","en":"It's his turn now.","ru":"Теперь его очередь.","vi":"Bây giờ đến lượt anh ấy.","fa":"حالا نوبت اوست"}]},{"word":"die Reihenfolge","en":"order; sequence","ru":"последовательность; порядок","vi":"thứ tự","fa":"سفارش","examples":[{"de":"Bitte beachten Sie die Reihenfolge der Aufgaben.","en":"Please pay attention to the order of the tasks.","ru":"Пожалуйста, соблюдайте порядок выполнения заданий.","vi":"Hãy lưu ý thứ tự các công việc.","fa":"لطفا به ترتیب وظایف توجه کنید."},{"de":"Die Namen stehen in alphabetischer Reihenfolge.","en":"The names are in alphabetical order.","ru":"Имена расположены в алфавитном порядке.","vi":"Các tên được sắp xếp theo thứ tự bảng chữ cái.","fa":"اسامی به ترتیب حروف الفبا می باشد."}]},{"word":"rein","en":"pure; clean","ru":"чистый","vi":"tinh khiết","fa":"خالص","examples":[{"de":"Das ist reines Gold.","en":"This is pure gold.","ru":"Это чистое золото.","vi":"Đây là vàng nguyên chất.","fa":"این طلای خالص است."},{"de":"Die Luft in den Bergen ist sehr rein.","en":"The air in the mountains is very clean.","ru":"Воздух в горах очень чистый.","vi":"Không khí trên núi rất trong lành.","fa":"هوای کوهستان بسیار تمیز است."}]},{"word":"reinigen","en":"to clean","ru":"чистить","vi":"sạch sẽ","fa":"تمیز کردن","examples":[{"de":"Wir lassen den Teppich professionell reinigen.","en":"We have the carpet cleaned professionally.","ru":"Мы отдаём ковёр на профессиональную чистку.","vi":"Chúng tôi giặt thảm một cách chuyên nghiệp.","fa":"ما فرش را به صورت حرفه ای تمیز می کنیم."},{"de":"Reinige die Wunde vorsichtig mit Wasser.","en":"Clean the wound carefully with water.","ru":"Аккуратно промой рану водой.","vi":"Nhẹ nhàng làm sạch vết thương bằng nước.","fa":"به آرامی زخم را با آب تمیز کنید."}]},{"word":"der Reis","en":"rice","ru":"рис","vi":"cơm","fa":"برنج","examples":[{"de":"Zum Mittagessen gibt es Reis mit Gemüse.","en":"For lunch there is rice with vegetables.","ru":"На обед рис с овощами.","vi":"Bữa trưa có cơm với rau.","fa":"برای ناهار برنج با سبزیجات وجود دارد."},{"de":"In Asien ist Reis ein Grundnahrungsmittel.","en":"In Asia, rice is a staple food.","ru":"В Азии рис — основной продукт питания.","vi":"Ở châu Á, gạo là lương thực chính.","fa":"در آسیا، برنج یک غذای اصلی است."}]},{"word":"reisen","en":"to travel","ru":"путешествовать","vi":"du lịch","fa":"سفر","examples":[{"de":"Wir reisen jedes Jahr in ein anderes Land.","en":"We travel to a different country every year.","ru":"Мы каждый год путешествуем в другую страну.","vi":"Chúng tôi đi du lịch đến một đất nước khác nhau mỗi năm.","fa":"ما هر سال به کشور دیگری سفر می کنیم."},{"de":"Sie reist gern allein.","en":"She likes to travel alone.","ru":"Она любит путешествовать одна.","vi":"Cô ấy thích đi du lịch một mình.","fa":"او دوست دارد به تنهایی سفر کند."}]},{"word":"der Reiseproviant","en":"travel provisions","ru":"дорожный провиант, еда в дорогу","vi":"quy định du lịch","fa":"مقررات سفر","examples":[{"de":"Wir haben genug Reiseproviant für die lange Fahrt.","en":"We have enough travel provisions for the long trip.","ru":"У нас достаточно провианта на долгую дорогу.","vi":"Chúng tôi có đủ lương thực cho cuộc hành trình dài.","fa":"ما آذوقه کافی برای سفر طولانی داریم."},{"de":"Vergiss den Reiseproviant nicht im Zug.","en":"Don't forget the travel provisions on the train.","ru":"Не забудь провиант в поезде.","vi":"Đừng quên đồ dùng du lịch của bạn trên tàu.","fa":"وسایل سفر خود را در قطار فراموش نکنید."},{"de":"Als Reiseproviant nehme ich immer Obst mit.","en":"As travel provisions I always take fruit with me.","ru":"В дорогу я всегда беру с собой фрукты.","vi":"Tôi luôn mang theo trái cây làm đồ dùng du lịch.","fa":"من همیشه میوه را به عنوان آذوقه سفرم با خود می برم."}]},{"word":"reiten","en":"to ride (a horse)","ru":"ездить верхом","vi":"đi xe","fa":"سوار شدن","examples":[{"de":"Meine Tochter reitet jeden Samstag.","en":"My daughter rides a horse every Saturday.","ru":"Моя дочь катается верхом каждую субботу.","vi":"Con gái tôi đi xe vào thứ Bảy hàng tuần.","fa":"دخترم هر شنبه سوار می شود."},{"de":"Kannst du reiten?","en":"Can you ride a horse?","ru":"Ты умеешь ездить верхом?","vi":"Bạn có thể đi xe không?","fa":"آیا می توانید سوار شوید؟"}]},{"word":"die Reklame","en":"advertisement","ru":"реклама","vi":"quảng cáo","fa":"تبلیغ","examples":[{"de":"Im Fernsehen läuft ständig Reklame.","en":"There are constantly advertisements on TV.","ru":"По телевизору постоянно идёт реклама.","vi":"Có những quảng cáo liên tục trên truyền hình.","fa":"تبلیغات دائمی در تلویزیون وجود دارد."},{"de":"Diese Reklame gefällt mir gar nicht.","en":"I don't like this advertisement at all.","ru":"Мне совсем не нравится эта реклама.","vi":"Tôi không thích quảng cáo này chút nào.","fa":"من اصلا از این تبلیغ خوشم نمیاد"}]},{"word":"reklamieren","en":"to make a complaint, return faulty goods","ru":"предъявлять претензию, возвращать бракованный товар","vi":"phàn nàn","fa":"شکایت کردن","examples":[{"de":"Ich möchte diese Schuhe reklamieren, sie sind kaputt.","en":"I'd like to return these shoes, they're broken.","ru":"Я хотел бы вернуть эти туфли, они бракованные.","vi":"Tôi muốn phàn nàn về đôi giày này, chúng bị hỏng rồi.","fa":"من می خواهم از این کفش ها شکایت کنم، آنها شکسته اند."},{"de":"Sie hat die Rechnung reklamiert, weil der Betrag falsch war.","en":"She complained about the bill because the amount was wrong.","ru":"Она оспорила счёт, потому что сумма была неверной.","vi":"Cô phàn nàn về hóa đơn vì số tiền không chính xác.","fa":"او از این صورت حساب شکایت کرد زیرا مبلغ آن نادرست بود."},{"de":"Wenn das Gerät nicht funktioniert, kannst du es reklamieren.","en":"If the device doesn't work, you can make a complaint.","ru":"Если прибор не работает, можно предъявить претензию.","vi":"Nếu thiết bị không hoạt động, bạn có thể khiếu nại về nó.","fa":"اگر دستگاه کار نمی کند، می توانید در مورد آن شکایت کنید."}]},{"word":"der Rekord","en":"record","ru":"рекорд","vi":"kỷ lục","fa":"رکورد","examples":[{"de":"Er hat einen neuen Rekord im Weitsprung aufgestellt.","en":"He set a new record in the long jump.","ru":"Он установил новый рекорд в прыжках в длину.","vi":"Anh lập kỷ lục mới ở nội dung nhảy xa.","fa":"او رکورد جدیدی در پرش طول به ثبت رساند."},{"de":"Dieses Jahr wurde ein Hitzerekord gemessen.","en":"This year a heat record was measured.","ru":"В этом году был зафиксирован рекорд жары.","vi":"Một đợt nắng nóng kỷ lục đã được ghi nhận trong năm nay.","fa":"رکورد گرمای امسال ثبت شد."}]},{"word":"relativ","en":"relative; relatively","ru":"относительный; относительно","vi":"tương đối","fa":"نسبی","examples":[{"de":"Die Wohnung ist relativ klein, aber gemütlich.","en":"The apartment is relatively small but cozy.","ru":"Квартира относительно маленькая, но уютная.","vi":"Căn hộ tương đối nhỏ nhưng ấm cúng.","fa":"آپارتمان نسبتا کوچک اما دنج است."},{"de":"Alles ist relativ, sagt man.","en":"Everything is relative, as they say.","ru":"Всё относительно, как говорится.","vi":"Mọi thứ đều tương đối, họ nói.","fa":"می گویند همه چیز نسبی است."}]},{"word":"die Religion","en":"religion","ru":"религия","vi":"tôn giáo","fa":"دین","examples":[{"de":"In der Schule haben wir auch Religion als Fach.","en":"At school we also have religion as a subject.","ru":"В школе у нас есть предмет «религия».","vi":"Chúng tôi cũng lấy tôn giáo làm môn học ở trường.","fa":"در مدرسه هم درس دین داریم."},{"de":"Er interessiert sich sehr für verschiedene Religionen.","en":"He is very interested in different religions.","ru":"Он очень интересуется разными религиями.","vi":"Anh ấy rất quan tâm đến các tôn giáo khác nhau.","fa":"علاقه زیادی به ادیان مختلف دارد."}]},{"word":"rennen","en":"to run","ru":"бежать","vi":"chạy","fa":"اجرا کنید","examples":[{"de":"Die Kinder rennen über die Wiese.","en":"The children are running across the meadow.","ru":"Дети бегут по лугу.","vi":"Những đứa trẻ chạy qua đồng cỏ.","fa":"بچه ها از آن سوی چمنزار می دوند."},{"de":"Ich musste zum Bus rennen, um ihn noch zu erreichen.","en":"I had to run to the bus to still catch it.","ru":"Мне пришлось бежать к автобусу, чтобы успеть на него.","vi":"Tôi phải chạy ra xe buýt để bắt nó.","fa":"مجبور شدم به سمت اتوبوس بروم تا آن را بگیرم."}]},{"word":"renovieren","en":"to renovate, do up","ru":"делать ремонт, ремонтировать","vi":"đổi mới","fa":"بازسازی کند","examples":[{"de":"Wir renovieren gerade unsere Wohnung.","en":"We're renovating our flat at the moment.","ru":"Сейчас мы делаем ремонт в квартире.","vi":"Chúng tôi hiện đang cải tạo căn hộ của mình.","fa":"ما در حال حاضر در حال بازسازی آپارتمان خود هستیم."},{"de":"Das Bad muss dringend renoviert werden.","en":"The bathroom urgently needs renovating.","ru":"Ванную срочно надо отремонтировать.","vi":"Phòng tắm cần được cải tạo khẩn cấp.","fa":"حمام نیاز فوری به بازسازی دارد."},{"de":"Nach dem Auszug haben wir die Räume renoviert.","en":"After moving out, we did up the rooms.","ru":"После переезда мы отремонтировали комнаты.","vi":"Sau khi chuyển đi, chúng tôi đã sửa sang lại các phòng.","fa":"بعد از نقل مکان، اتاق ها را بازسازی کردیم."}]},{"word":"die Rente","en":"pension","ru":"пенсия","vi":"lương hưu","fa":"حقوق بازنشستگی","examples":[{"de":"Mein Opa bekommt seit fünf Jahren Rente.","en":"My grandpa has been receiving a pension for five years.","ru":"Мой дедушка получает пенсию уже пять лет.","vi":"Ông tôi đã nhận được tiền trợ cấp được 5 năm rồi.","fa":"پدربزرگ من پنج سال است که مستمری می گیرد."},{"de":"Sie geht nächstes Jahr in Rente.","en":"She is retiring next year.","ru":"В следующем году она выходит на пенсию.","vi":"Cô ấy sẽ nghỉ hưu vào năm tới.","fa":"او سال آینده بازنشسته می شود."}]},{"word":"die Rentenversicherung","en":"pension insurance; state pension scheme","ru":"пенсионное страхование, государственная пенсионная система","vi":"bảo hiểm hưu trí","fa":"بیمه بازنشستگی","examples":[{"de":"Jeder Arbeitnehmer zahlt in die Rentenversicherung ein.","en":"Every employee pays into the pension insurance scheme.","ru":"Каждый работник платит взносы в пенсионное страхование.","vi":"Mỗi nhân viên đều đóng vào bảo hiểm hưu trí.","fa":"هر کارمندی به بیمه بازنشستگی پرداخت می کند."},{"de":"Die gesetzliche Rentenversicherung ist in Deutschland wichtig.","en":"The statutory pension insurance is important in Germany.","ru":"Государственное пенсионное страхование важно в Германии.","vi":"Bảo hiểm hưu trí theo luật định rất quan trọng ở Đức.","fa":"بیمه بازنشستگی قانونی در آلمان مهم است."},{"de":"Von der Rentenversicherung bekommt man später eine Rente.","en":"You receive a pension from the pension insurance scheme later on.","ru":"Позже вы получаете пенсию от системы пенсионного страхования.","vi":"Sau này bạn sẽ nhận được lương hưu từ bảo hiểm hưu trí.","fa":"بعداً از بیمه بازنشستگی مستمری دریافت خواهید کرد."}]},{"word":"reparieren","en":"to repair","ru":"ремонтировать","vi":"sửa chữa","fa":"تعمیر","examples":[{"de":"Der Mechaniker repariert mein Auto.","en":"The mechanic is repairing my car.","ru":"Механик ремонтирует мою машину.","vi":"Người thợ sửa xe của tôi.","fa":"مکانیک ماشین من را تعمیر می کند."},{"de":"Kannst du das kaputte Fahrrad reparieren?","en":"Can you repair the broken bicycle?","ru":"Ты можешь починить сломанный велосипед?","vi":"Bạn có thể sửa chiếc xe đạp bị hỏng không?","fa":"آیا می توانید دوچرخه شکسته را تعمیر کنید؟"}]},{"word":"die Reportage","en":"report; documentary","ru":"репортаж","vi":"báo cáo","fa":"گزارش","examples":[{"de":"Im Radio lief eine interessante Reportage über den Klimawandel.","en":"There was an interesting report about climate change on the radio.","ru":"По радио шёл интересный репортаж об изменении климата.","vi":"Có một báo cáo thú vị về biến đổi khí hậu trên đài phát thanh.","fa":"گزارش جالبی در مورد تغییرات آب و هوایی از رادیو پخش شد."},{"de":"Sie schreibt eine Reportage über das Leben auf dem Land.","en":"She is writing a report about life in the countryside.","ru":"Она пишет репортаж о жизни в деревне.","vi":"Cô ấy viết một bản báo cáo về cuộc sống ở đất nước.","fa":"او گزارشی از زندگی در کشور می نویسد."}]},{"word":"der Reporter","en":"reporter (male)","ru":"репортёр (мужчина)","vi":"phóng viên","fa":"خبرنگار","examples":[{"de":"Der Reporter stellte dem Bürgermeister viele kritische Fragen.","en":"The reporter asked the mayor many critical questions.","ru":"Репортёр задал мэру много острых вопросов.","vi":"Phóng viên đã hỏi thị trưởng nhiều câu hỏi quan trọng.","fa":"خبرنگار سوالات انتقادی زیادی از شهردار پرسید."},{"de":"Als Reporter muss man oft am Wochenende arbeiten.","en":"As a reporter you often have to work at the weekend.","ru":"Как репортёру, тебе часто приходится работать по выходным.","vi":"Là một phóng viên, bạn thường phải làm việc vào cuối tuần.","fa":"به عنوان یک خبرنگار اغلب باید در تعطیلات آخر هفته کار کنید."},{"de":"Ein Reporter berichtete live vom Fußballspiel.","en":"A reporter reported live from the football match.","ru":"Репортёр вёл прямой репортаж с футбольного матча.","vi":"Một phóng viên đưa tin trực tiếp từ trận đấu bóng đá.","fa":"خبرنگاری از بازی فوتبال به صورت زنده گزارش داد."}]},{"word":"die Reporterin","en":"reporter (female)","ru":"репортёрша (женщина)","vi":"phóng viên","fa":"خبرنگار","examples":[{"de":"Die Reporterin interviewte die berühmte Schauspielerin.","en":"The reporter interviewed the famous actress.","ru":"Репортёрша взяла интервью у знаменитой актрисы.","vi":"Phóng viên phỏng vấn nữ diễn viên nổi tiếng.","fa":"خبرنگار با بازیگر معروف مصاحبه کرد."},{"de":"Als Reporterin reist sie viel durch die ganze Welt.","en":"As a reporter she travels a lot all over the world.","ru":"Как репортёрша, она много ездит по всему миру.","vi":"Là một phóng viên, cô đi du lịch rất nhiều nơi trên thế giới.","fa":"او به عنوان یک گزارشگر به سراسر جهان سفر می کند."},{"de":"Die Reporterin schrieb einen Artikel über die Demonstration.","en":"The reporter wrote an article about the demonstration.","ru":"Репортёрша написала статью о демонстрации.","vi":"Phóng viên đã viết một bài báo về cuộc biểu tình.","fa":"خبرنگار مقاله ای در مورد تظاهرات نوشت."}]},{"word":"reservieren","en":"to reserve; to book","ru":"бронировать","vi":"dự trữ","fa":"رزرو کنید","examples":[{"de":"Ich habe einen Tisch für zwei Personen reserviert.","en":"I have reserved a table for two people.","ru":"Я забронировал столик на двоих.","vi":"Tôi đã đặt bàn cho hai người.","fa":"من یک میز برای دو نفر رزرو کردم."},{"de":"Reservieren Sie bitte die Karten im Voraus.","en":"Please book the tickets in advance.","ru":"Пожалуйста, забронируйте билеты заранее.","vi":"Vui lòng đặt vé trước.","fa":"لطفا بلیط را از قبل رزرو کنید."}]},{"word":"der Respekt","en":"respect","ru":"уважение","vi":"sự tôn trọng","fa":"احترام","examples":[{"de":"Man sollte immer Respekt vor älteren Menschen haben.","en":"One should always have respect for older people.","ru":"Нужно всегда уважать пожилых людей.","vi":"Người ta phải luôn tôn trọng người lớn tuổi.","fa":"همیشه باید به افراد مسن احترام گذاشت."},{"de":"Er hat großen Respekt vor seiner Lehrerin.","en":"He has great respect for his teacher.","ru":"Он очень уважает свою учительницу.","vi":"Anh ấy rất tôn trọng giáo viên của mình.","fa":"او برای معلمش احترام زیادی قائل است."}]},{"word":"der Rest","en":"rest; remainder","ru":"остаток","vi":"phần còn lại","fa":"بقیه","examples":[{"de":"Den Rest des Kuchens können wir morgen essen.","en":"We can eat the rest of the cake tomorrow.","ru":"Остаток торта мы можем съесть завтра.","vi":"Chúng ta có thể ăn phần còn lại của chiếc bánh vào ngày mai.","fa":"بقیه کیک را فردا می توانیم بخوریم."},{"de":"Ich habe nur noch den Rest meines Geldes dabei.","en":"I only have the rest of my money with me.","ru":"У меня с собой остались только остатки денег.","vi":"Tôi chỉ mang theo số tiền còn lại.","fa":"من فقط بقیه پولم را با خودم دارم."}]},{"word":"das Restaurant","en":"restaurant","ru":"ресторан","vi":"nhà hàng","fa":"رستوران","examples":[{"de":"Wir gehen heute Abend in ein neues Restaurant.","en":"We are going to a new restaurant tonight.","ru":"Сегодня вечером мы идём в новый ресторан.","vi":"Tối nay chúng ta sẽ đi đến một nhà hàng mới.","fa":"ما امشب به یک رستوران جدید می رویم."},{"de":"Das Restaurant ist für seine Pasta bekannt.","en":"The restaurant is known for its pasta.","ru":"Ресторан известен своей пастой.","vi":"Nhà hàng được biết đến với món mì ống.","fa":"این رستوران به خاطر پاستاهایش معروف است."}]},{"word":"retten","en":"to save; to rescue","ru":"спасать","vi":"lưu lại","fa":"ذخیره کنید","examples":[{"de":"Die Feuerwehr konnte alle Bewohner retten.","en":"The fire department was able to save all the residents.","ru":"Пожарные смогли спасти всех жителей.","vi":"Sở cứu hỏa đã có thể cứu tất cả cư dân.","fa":"آتش نشانی توانست همه ساکنان را نجات دهد."},{"de":"Er hat dem Kind das Leben gerettet.","en":"He saved the child's life.","ru":"Он спас ребёнку жизнь.","vi":"Anh ấy đã cứu mạng đứa trẻ.","fa":"او جان کودک را نجات داد."}]},{"word":"die Rettung","en":"rescue; salvation","ru":"спасение","vi":"cuộc giải cứu","fa":"نجات","examples":[{"de":"Die Rettung der Bergsteiger dauerte mehrere Stunden.","en":"The rescue of the climbers took several hours.","ru":"Спасение альпинистов заняло несколько часов.","vi":"Việc giải cứu những người leo núi mất vài giờ.","fa":"نجات کوهنوردان چند ساعت طول کشید."},{"de":"In letzter Sekunde kam die Rettung.","en":"Rescue came at the last second.","ru":"Спасение пришло в последнюю секунду.","vi":"Sự giải cứu đến vào giây cuối cùng.","fa":"نجات در آخرین ثانیه آمد."}]},{"word":"das Rezept","en":"recipe; prescription","ru":"рецепт","vi":"công thức","fa":"دستور غذا","examples":[{"de":"Meine Oma hat mir ihr Rezept für Apfelkuchen gegeben.","en":"My grandma gave me her recipe for apple cake.","ru":"Бабушка дала мне свой рецепт яблочного пирога.","vi":"Bà tôi đã cho tôi công thức làm bánh táo của bà.","fa":"مادربزرگم دستور پای سیب را به من داد."},{"de":"Dieses Medikament bekommt man nur auf Rezept.","en":"You can only get this medicine with a prescription.","ru":"Это лекарство можно получить только по рецепту.","vi":"Thuốc này chỉ có sẵn với một toa thuốc.","fa":"این دارو فقط با نسخه در دسترس است."}]},{"word":"die Rezeption/Reception","en":"reception (desk)","ru":"стойка регистрации; ресепшн","vi":"sự đón tiếp/sự đón tiếp","fa":"پذیرش / پذیرایی","examples":[{"de":"Den Schlüssel bekommen Sie an der Rezeption.","en":"You will get the key at the reception.","ru":"Ключ вы получите на стойке регистрации.","vi":"Bạn có thể lấy chìa khóa tại quầy lễ tân.","fa":"می توانید کلید را در پذیرش دریافت کنید."},{"de":"Bitte melden Sie sich zuerst an der Reception.","en":"Please check in at reception first.","ru":"Пожалуйста, сначала обратитесь на ресепшн.","vi":"Vui lòng báo cáo cho lễ tân trước.","fa":"لطفا ابتدا به پذیرش گزارش دهید."}]},{"word":"der Rhythmus","en":"rhythm","ru":"ритм","vi":"nhịp điệu","fa":"ریتم","examples":[{"de":"Ohne ein Gefühl für den Rhythmus fällt das Tanzen schwer.","en":"Without a feel for the rhythm, dancing is difficult.","ru":"Без чувства ритма танцевать трудно.","vi":"Khiêu vũ rất khó nếu không có cảm giác nhịp điệu.","fa":"رقصیدن بدون حس ریتم سخت است."},{"de":"Der Schlagzeuger hielt den ganzen Abend einen sauberen Rhythmus.","en":"The drummer kept a clean rhythm all evening.","ru":"Барабанщик весь вечер держал чёткий ритм.","vi":"Tay trống giữ nhịp điệu rõ ràng suốt buổi tối.","fa":"درامر در تمام طول شب ریتم تمیزی را حفظ کرد."},{"de":"Im Laufe der Woche fand sie wieder ihren gewohnten Rhythmus.","en":"Over the course of the week she found her usual rhythm again.","ru":"В течение недели она снова вошла в привычный ритм.","vi":"Trong suốt tuần đó, cô đã tìm lại được nhịp điệu bình thường của mình.","fa":"در طول هفته او دوباره ریتم معمول خود را پیدا کرد."}]},{"word":"der Richter","en":"judge","ru":"судья","vi":"thẩm phán","fa":"قاضی","examples":[{"de":"Der Richter entscheidet über den Fall.","en":"The judge decides the case.","ru":"Судья принимает решение по делу.","vi":"Thẩm phán quyết định vụ án.","fa":"قاضی در مورد پرونده تصمیم گیری می کند."},{"de":"Sie möchte später Richterin werden.","en":"She wants to become a judge later.","ru":"Позже она хочет стать судьёй.","vi":"Cô bé muốn trở thành thẩm phán khi lớn lên.","fa":"او می خواهد وقتی بزرگ شد قاضی شود."}]},{"word":"die Richterin","en":"judge (female)","ru":"судья (женщина)","vi":"thẩm phán","fa":"قاضی","examples":[{"de":"Die Richterin stellte dem Zeugen mehrere Fragen.","en":"The judge asked the witness several questions.","ru":"Судья задала свидетелю несколько вопросов.","vi":"Thẩm phán hỏi nhân chứng một số câu hỏi.","fa":"قاضی چندین سوال از شاهد پرسید."},{"de":"Die Richterin verlas das Urteil mit ruhiger Stimme.","en":"The judge read out the verdict in a calm voice.","ru":"Судья спокойным голосом зачитала приговор.","vi":"Thẩm phán đọc bản án với giọng bình tĩnh.","fa":"قاضی با صدایی آرام حکم را خواند."},{"de":"Eine erfahrene Richterin leitete die Verhandlung.","en":"An experienced judge led the trial.","ru":"Опытная судья вела процесс.","vi":"Một thẩm phán giàu kinh nghiệm chủ trì phiên điều trần.","fa":"یک قاضی با تجربه ریاست جلسه را بر عهده داشت."}]},{"word":"richtig","en":"correct; right","ru":"правильный","vi":"đúng","fa":"درست است","examples":[{"de":"Deine Antwort ist richtig.","en":"Your answer is correct.","ru":"Твой ответ правильный.","vi":"Câu trả lời của bạn là chính xác.","fa":"پاسخ شما درست است."},{"de":"Das war die richtige Entscheidung.","en":"That was the right decision.","ru":"Это было правильное решение.","vi":"Đó là quyết định đúng đắn.","fa":"این تصمیم درستی بود."}]},{"word":"die Richtung","en":"direction","ru":"направление","vi":"phương hướng","fa":"جهت","examples":[{"de":"Wir fahren in die falsche Richtung.","en":"We are driving in the wrong direction.","ru":"Мы едем в неправильном направлении.","vi":"Chúng ta đang đi sai hướng.","fa":"ما در مسیر اشتباهی می رویم."},{"de":"Können Sie mir die Richtung zum Bahnhof zeigen?","en":"Can you show me the direction to the train station?","ru":"Можете показать мне направление к вокзалу?","vi":"Bạn có thể chỉ cho tôi đường đến ga xe lửa được không?","fa":"آیا می توانید مسیر ایستگاه قطار را به من نشان دهید؟"}]},{"word":"riechen","en":"to smell","ru":"пахнуть; чувствовать запах","vi":"mùi","fa":"بو","examples":[{"de":"Die Blumen riechen sehr gut.","en":"The flowers smell very good.","ru":"Цветы очень хорошо пахнут.","vi":"Hoa có mùi rất thơm.","fa":"گلها بوی بسیار خوبی دارند."},{"de":"Ich rieche Rauch, brennt hier etwas?","en":"I smell smoke, is something burning here?","ru":"Я чувствую запах дыма, здесь что-то горит?","vi":"Tôi ngửi thấy mùi khói, có thứ gì đang cháy ở đây à?","fa":"بوی دود می دهم، چیزی اینجا می سوزد؟"}]},{"word":"riesig","en":"huge; enormous","ru":"огромный","vi":"to lớn","fa":"بزرگ","examples":[{"de":"Sie wohnen in einem riesigen Haus.","en":"They live in a huge house.","ru":"Они живут в огромном доме.","vi":"Họ sống trong một ngôi nhà lớn.","fa":"آنها در یک خانه بزرگ زندگی می کنند."},{"de":"Das war ein riesiger Erfolg.","en":"That was a huge success.","ru":"Это был огромный успех.","vi":"Đó là một thành công lớn.","fa":"این یک موفقیت بزرگ بود."}]},{"word":"das Rind","en":"cattle; beef","ru":"крупный рогатый скот; говядина","vi":"thịt bò","fa":"گوشت گاو","examples":[{"de":"Auf dem Bauernhof stehen viele Rinder auf der Weide.","en":"There are many cattle grazing on the farm.","ru":"На ферме на пастбище пасётся много коров.","vi":"Trong trang trại có rất nhiều gia súc đang chăn thả.","fa":"گاوهای زیادی در مزرعه در حال چرا هستند."},{"de":"Zum Abendessen gibt es Rind mit Kartoffeln.","en":"For dinner there is beef with potatoes.","ru":"На ужин говядина с картофелем.","vi":"Bữa tối có thịt bò với khoai tây.","fa":"برای شام گوشت گاو با سیب زمینی وجود دارد."}]},{"word":"der Ring","en":"ring","ru":"кольцо","vi":"chiếc nhẫn","fa":"حلقه","examples":[{"de":"Er hat ihr einen goldenen Ring geschenkt.","en":"He gave her a golden ring.","ru":"Он подарил ей золотое кольцо.","vi":"Anh tặng cô một chiếc nhẫn vàng.","fa":"یک انگشتر طلا به او داد."},{"de":"Sie trägt den Ring an der rechten Hand.","en":"She wears the ring on her right hand.","ru":"Она носит кольцо на правой руке.","vi":"Cô đeo chiếc nhẫn ở tay phải.","fa":"او حلقه را در دست راست خود می بندد."}]},{"word":"das Risiko","en":"risk","ru":"риск","vi":"rủi ro","fa":"خطر","examples":[{"de":"Das ist ein zu großes Risiko für mich.","en":"That is too big a risk for me.","ru":"Это слишком большой риск для меня.","vi":"Đó là một rủi ro quá lớn đối với tôi.","fa":"این برای من یک ریسک بزرگ است."},{"de":"Rauchen erhöht das Risiko für Krankheiten.","en":"Smoking increases the risk of diseases.","ru":"Курение повышает риск заболеваний.","vi":"Hút thuốc làm tăng nguy cơ mắc bệnh.","fa":"سیگار خطر ابتلا به بیماری را افزایش می دهد."}]},{"word":"der Rock","en":"skirt","ru":"юбка","vi":"váy","fa":"دامن","examples":[{"de":"Sie trägt einen kurzen Rock.","en":"She is wearing a short skirt.","ru":"Она носит короткую юбку.","vi":"Cô ấy đang mặc một chiếc váy ngắn.","fa":"او یک دامن کوتاه پوشیده است."},{"de":"Der Rock passt gut zu der Bluse.","en":"The skirt goes well with the blouse.","ru":"Юбка хорошо сочетается с блузкой.","vi":"Chiếc váy rất hợp với áo cánh.","fa":"دامن به خوبی با بلوز ست می شود."}]},{"word":"roh","en":"raw","ru":"сырой (необработанный)","vi":"thô","fa":"خام","examples":[{"de":"Man sollte kein rohes Fleisch essen.","en":"One should not eat raw meat.","ru":"Не следует есть сырое мясо.","vi":"Bạn không nên ăn thịt sống.","fa":"شما نباید گوشت خام بخورید."},{"de":"Das Gemüse schmeckt roh am besten.","en":"The vegetables taste best raw.","ru":"Овощи вкуснее всего в сыром виде.","vi":"Các loại rau có vị tươi ngon nhất.","fa":"طعم سبزیجات خام بهتر است."}]},{"word":"das Rohr","en":"pipe, tube","ru":"труба (трубопровод)","vi":"cái ống","fa":"لوله","examples":[{"de":"Das Rohr unter der Spüle ist undicht.","en":"The pipe under the sink is leaking.","ru":"Труба под раковиной протекает.","vi":"Đường ống dưới bồn rửa bị rò rỉ.","fa":"لوله زیر سینک نشتی دارد."},{"de":"Der Klempner musste ein altes Rohr austauschen.","en":"The plumber had to replace an old pipe.","ru":"Сантехнику пришлось заменить старую трубу.","vi":"Thợ sửa ống nước đã phải thay một đường ống cũ.","fa":"لوله کش مجبور شد یک لوله قدیمی را جایگزین کند."},{"de":"Durch dieses Rohr fließt das warme Wasser ins Haus.","en":"The warm water flows into the house through this pipe.","ru":"Тёплая вода поступает в дом по этой трубе.","vi":"Nước ấm chảy vào nhà qua đường ống này.","fa":"آب گرم از طریق این لوله وارد خانه می شود."}]},{"word":"der Rohstoff","en":"raw material","ru":"сырьё","vi":"nguyên liệu thô","fa":"مواد خام","examples":[{"de":"Viele Rohstoffe auf der Erde sind begrenzt.","en":"Many raw materials on Earth are limited.","ru":"Многие виды сырья на Земле ограничены.","vi":"Nhiều nguyên liệu thô trên trái đất bị hạn chế.","fa":"بسیاری از مواد خام روی زمین محدود هستند."},{"de":"Recycling spart wertvolle Rohstoffe.","en":"Recycling saves valuable raw materials.","ru":"Переработка экономит ценное сырьё.","vi":"Tái chế tiết kiệm nguyên liệu thô có giá trị.","fa":"بازیافت باعث صرفه جویی در مواد خام با ارزش می شود."},{"de":"Für Handys braucht man seltene Rohstoffe.","en":"You need rare raw materials for mobile phones.","ru":"Для телефонов нужно редкое сырьё.","vi":"Nguyên liệu quý hiếm cần thiết cho điện thoại di động.","fa":"مواد اولیه کمیاب برای تلفن های همراه مورد نیاز است."}]},{"word":"die Rolle","en":"role","ru":"роль","vi":"vai trò","fa":"نقش","examples":[{"de":"Er spielt die Hauptrolle in dem neuen Film.","en":"He plays the main role in the new film.","ru":"Он играет главную роль в новом фильме.","vi":"Anh đóng vai chính trong bộ phim mới.","fa":"او در فیلم جدید نقش اصلی را بازی می کند."},{"de":"Geld spielt für ihn keine große Rolle.","en":"Money doesn't play a big role for him.","ru":"Деньги не играют для него большой роли.","vi":"Tiền không đóng một vai trò lớn đối với anh ta.","fa":"پول برای او نقش چندانی ندارد."}]},{"word":"das Rollenspiel","en":"role-play","ru":"ролевая игра","vi":"đóng vai","fa":"بازی نقش","examples":[{"de":"Im Deutschkurs machen wir oft ein Rollenspiel.","en":"In the German course we often do a role-play.","ru":"На курсе немецкого мы часто устраиваем ролевую игру.","vi":"Trong khóa học tiếng Đức, chúng tôi thường thực hiện việc đóng vai.","fa":"در دوره آلمانی ما اغلب نقش بازی می کنیم."},{"de":"Beim Rollenspiel hat jeder Teilnehmer eine bestimmte Aufgabe.","en":"In the role-play each participant has a particular task.","ru":"В ролевой игре у каждого участника своя задача.","vi":"Trong trò chơi đóng vai, mỗi người tham gia có một nhiệm vụ cụ thể.","fa":"در بازی نقش، هر شرکت کننده وظیفه خاصی دارد."},{"de":"Das Rollenspiel half den Schülern, frei zu sprechen.","en":"The role-play helped the pupils to speak freely.","ru":"Ролевая игра помогла ученикам говорить свободнее.","vi":"Việc đóng vai giúp học sinh nói chuyện một cách tự do.","fa":"بازی نقش به دانش آموزان کمک کرد تا آزادانه صحبت کنند."}]},{"word":"der Roman","en":"novel","ru":"роман (книга)","vi":"cuốn tiểu thuyết","fa":"رمان","examples":[{"de":"Ich lese gerade einen spannenden Roman.","en":"I am currently reading an exciting novel.","ru":"Я сейчас читаю увлекательный роман.","vi":"Tôi hiện đang đọc một cuốn tiểu thuyết thú vị.","fa":"در حال حاضر در حال خواندن یک رمان هیجان انگیز هستم."},{"de":"Sie hat ihren ersten Roman mit 25 Jahren veröffentlicht.","en":"She published her first novel at the age of 25.","ru":"Она опубликовала свой первый роман в 25 лет.","vi":"Cô xuất bản cuốn tiểu thuyết đầu tiên của mình ở tuổi 25.","fa":"او اولین رمان خود را در 25 سالگی منتشر کرد."}]},{"word":"die Rose","en":"rose","ru":"роза","vi":"hoa hồng","fa":"گل رز","examples":[{"de":"Er schenkte ihr einen Strauß roter Rosen.","en":"He gave her a bouquet of red roses.","ru":"Он подарил ей букет красных роз.","vi":"Anh tặng cô một bó hoa hồng đỏ.","fa":"او یک دسته گل رز قرمز به او داد."},{"de":"Im Garten blühen die Rosen im Juni.","en":"The roses bloom in the garden in June.","ru":"Розы в саду цветут в июне.","vi":"Hoa hồng nở trong vườn vào tháng Sáu.","fa":"گل های رز در ماه ژوئن در باغ شکوفا می شوند."}]},{"word":"die Routine","en":"routine","ru":"рутина, привычный порядок","vi":"thói quen","fa":"روال","examples":[{"de":"Eine feste Routine am Morgen tut mir gut.","en":"A fixed morning routine does me good.","ru":"Устойчивая утренняя рутина идёт мне на пользу.","vi":"Một thói quen cố định vào buổi sáng rất tốt cho tôi.","fa":"یک برنامه منظم در صبح برای من خوب است."},{"de":"Nach ein paar Wochen wird alles zur Routine.","en":"After a few weeks everything becomes routine.","ru":"Через несколько недель всё становится рутиной.","vi":"Sau một vài tuần, mọi thứ trở thành thói quen.","fa":"بعد از چند هفته همه چیز روتین می شود."},{"de":"Manchmal fehlt mir in der täglichen Routine die Abwechslung.","en":"Sometimes I miss variety in my daily routine.","ru":"Иногда мне не хватает разнообразия в повседневной рутине.","vi":"Đôi khi tôi bỏ lỡ sự đa dạng trong thói quen hàng ngày của mình.","fa":"گاهی اوقات دلم برای تنوع در برنامه روزانه ام تنگ می شود."}]},{"word":"rück-","en":"back-; return-","ru":"обратно-; назад-","vi":"quay lại-","fa":"پشت -","examples":[{"de":"Bitte geben Sie mir eine Rückmeldung, wenn Sie Zeit haben.","en":"Please give me feedback when you have time.","ru":"Пожалуйста, дайте мне обратную связь, когда у вас будет время.","vi":"Hãy cho tôi phản hồi khi bạn có thời gian.","fa":"لطفا در صورت داشتن وقت به من بازخورد بدهید."},{"de":"Nach dem Konzert machen wir uns auf den Rückweg.","en":"After the concert we head back.","ru":"После концерта мы отправляемся в обратный путь.","vi":"Sau buổi hòa nhạc, chúng tôi lên đường trở về.","fa":"بعد از کنسرت راه برگشت را طی می کنیم."}]},{"word":"der Rücken","en":"back (body part)","ru":"спина","vi":"mặt sau","fa":"پشت","examples":[{"de":"Mir tut der Rücken weh.","en":"My back hurts.","ru":"У меня болит спина.","vi":"Lưng tôi đau quá.","fa":"کمرم درد میکنه"},{"de":"Er trägt den Rucksack auf dem Rücken.","en":"He carries the backpack on his back.","ru":"Он несёт рюкзак на спине.","vi":"Anh ta đeo ba lô trên lưng.","fa":"او کوله پشتی را بر پشت خود حمل می کند."}]},{"word":"die Rückfrage","en":"query, follow-up question","ru":"уточняющий вопрос, повторный запрос","vi":"truy vấn","fa":"پرس و جو","examples":[{"de":"Bei Rückfragen können Sie mich jederzeit anrufen.","en":"If you have any queries, you can call me at any time.","ru":"Если возникнут вопросы, можешь звонить мне в любое время.","vi":"Nếu bạn có bất kỳ câu hỏi nào, bạn có thể gọi cho tôi bất cứ lúc nào.","fa":"اگر سوالی دارید، می توانید در هر زمان با من تماس بگیرید."},{"de":"Ich habe noch eine Rückfrage zu Ihrem Angebot.","en":"I still have a follow-up question about your offer.","ru":"У меня ещё есть уточняющий вопрос по вашему предложению.","vi":"Tôi có một câu hỏi khác về lời đề nghị của bạn.","fa":"من یک سوال دیگر در مورد پیشنهاد شما دارم."},{"de":"Nach kurzer Rückfrage beim Chef konnte ich den Termin bestätigen.","en":"After a quick query with the boss, I was able to confirm the appointment.","ru":"После короткого уточнения у начальника я смог подтвердить встречу.","vi":"Sau khi hỏi nhanh với sếp, tôi đã có thể xác nhận cuộc hẹn.","fa":"پس از یک پرس و جو سریع با رئیس، من توانستم قرار ملاقات را تأیید کنم."}]},{"word":"die Rückkehr","en":"return (coming back)","ru":"возвращение","vi":"sự trở lại","fa":"بازگشت","examples":[{"de":"Nach seiner Rückkehr aus dem Urlaub hatte er viel Arbeit.","en":"After his return from holiday he had a lot of work.","ru":"После возвращения из отпуска у него было много работы.","vi":"Sau khi trở về từ kỳ nghỉ, anh ấy có rất nhiều việc phải làm.","fa":"بعد از بازگشت از تعطیلات، کار زیادی داشت."},{"de":"Wir freuen uns alle auf deine Rückkehr.","en":"We are all looking forward to your return.","ru":"Мы все ждём твоего возвращения.","vi":"Tất cả chúng tôi đều mong chờ sự trở lại của bạn.","fa":"همه ما مشتاقانه منتظر بازگشت شما هستیم."},{"de":"Die Rückkehr in die Heimat war für sie sehr emotional.","en":"The return to her homeland was very emotional for her.","ru":"Возвращение на родину было для неё очень волнующим.","vi":"Việc trở về nhà khiến cô rất xúc động.","fa":"بازگشت به خانه برای او بسیار احساسی بود."}]},{"word":"das Rücklicht","en":"rear light, tail light","ru":"задний фонарь, стоп-сигнал","vi":"đèn hậu","fa":"چراغ عقب","examples":[{"de":"Das Rücklicht meines Fahrrads ist kaputt.","en":"The rear light on my bicycle is broken.","ru":"Задний фонарь на моём велосипеде сломан.","vi":"Đèn hậu xe đạp của tôi bị hỏng.","fa":"چراغ عقب دوچرخه ام خراب است."},{"de":"In der Dunkelheit muss das Rücklicht am Auto leuchten.","en":"In the dark the car's rear light has to be on.","ru":"В темноте задний фонарь машины должен быть включён.","vi":"Đèn hậu trên ô tô phải sáng trong bóng tối.","fa":"چراغ عقب خودرو باید در تاریکی روشن شود."},{"de":"Die Polizei hielt ihn an, weil ein Rücklicht nicht funktionierte.","en":"The police stopped him because one tail light wasn't working.","ru":"Полиция остановила его, потому что не работал один задний фонарь.","vi":"Cảnh sát đã chặn anh ta lại vì đèn hậu không hoạt động.","fa":"پلیس او را متوقف کرد زیرا چراغ عقب کار نمی کرد."}]},{"word":"der Rucksack","en":"backpack","ru":"рюкзак","vi":"ba lô","fa":"کوله پشتی","examples":[{"de":"Er packt seinen Rucksack für die Wanderung.","en":"He is packing his backpack for the hike.","ru":"Он собирает рюкзак для похода.","vi":"Anh ấy xách ba lô lên để đi bộ đường dài.","fa":"او کوله پشتی خود را برای پیاده روی می بندد."},{"de":"Mein Rucksack ist heute sehr schwer.","en":"My backpack is very heavy today.","ru":"Сегодня мой рюкзак очень тяжёлый.","vi":"Ba lô của tôi hôm nay rất nặng.","fa":"کوله پشتی من امروز خیلی سنگین است."}]},{"word":"der Rücksendeschein","en":"return slip, returns form","ru":"бланк возврата, накладная на возврат товара","vi":"phiếu trả lại","fa":"the return slip","examples":[{"de":"Legen Sie bitte den Rücksendeschein in das Paket.","en":"Please put the return slip into the parcel.","ru":"Пожалуйста, вложите бланк возврата в посылку.","vi":"Vui lòng đặt phiếu trả lại vào gói hàng.","fa":"لطفا برگه برگشت را در بسته قرار دهید."},{"de":"Den Rücksendeschein finden Sie in Ihrem Kundenkonto.","en":"You will find the return slip in your customer account.","ru":"Бланк возврата вы найдёте в своём личном кабинете.","vi":"Bạn có thể tìm thấy phiếu trả hàng trong tài khoản khách hàng của mình.","fa":"You can find the return slip in your customer account."},{"de":"Ohne Rücksendeschein kann die Ware nicht erstattet werden.","en":"Without the return slip the goods cannot be refunded.","ru":"Без бланка возврата стоимость товара не может быть возмещена.","vi":"Hàng hóa không thể được hoàn trả nếu không có phiếu trả lại.","fa":"کالا بدون برگه برگشت قابل استرداد نیست."}]},{"word":"die Rücksendung","en":"return (of goods)","ru":"возврат (товара)","vi":"sự trở lại","fa":"بازگشت","examples":[{"de":"Die Rücksendung der Schuhe ist für Sie kostenlos.","en":"The return of the shoes is free of charge for you.","ru":"Возврат обуви для вас бесплатный.","vi":"Việc trả lại giày là miễn phí cho bạn.","fa":"بازگرداندن کفش برای شما رایگان است."},{"de":"Bitte melden Sie die Rücksendung vorher online an.","en":"Please register the return online beforehand.","ru":"Пожалуйста, заранее оформите возврат онлайн.","vi":"Vui lòng đăng ký trả lại trực tuyến trước.","fa":"لطفا از قبل به صورت آنلاین ثبت نام کنید."},{"de":"Nach der Rücksendung erhalten Sie Ihr Geld zurück.","en":"After the return you will get your money back.","ru":"После возврата вы получите свои деньги обратно.","vi":"Sau khi trở về, bạn sẽ nhận lại được tiền của mình.","fa":"پس از بازگشت، پول خود را پس خواهید گرفت."}]},{"word":"die Rücksicht","en":"consideration","ru":"внимание к другим; тактичность","vi":"sự cân nhắc","fa":"در نظر گرفتن","examples":[{"de":"Bitte nimm Rücksicht auf die anderen Gäste.","en":"Please be considerate of the other guests.","ru":"Пожалуйста, будь внимателен к другим гостям.","vi":"Xin hãy quan tâm đến những vị khách khác.","fa":"لطفا مراقب سایر مهمانان باشید."},{"de":"Er fährt ohne jede Rücksicht auf andere Verkehrsteilnehmer.","en":"He drives without any consideration for other road users.","ru":"Он ездит совершенно не считаясь с другими участниками движения.","vi":"Anh ta lái xe mà không quan tâm đến những người tham gia giao thông khác.","fa":"او بدون توجه به سایر کاربران جاده رانندگی می کند."}]},{"word":"rücksichtsvoll","en":"considerate; thoughtful","ru":"внимательный; тактичный","vi":"ân cần","fa":"با ملاحظه","examples":[{"de":"Bitte sei rücksichtsvoll gegenüber den Nachbarn.","en":"Please be considerate towards the neighbours.","ru":"Пожалуйста, будь внимателен к соседям.","vi":"Xin hãy quan tâm đến hàng xóm.","fa":"لطفا مراقب همسایه ها باشید"},{"de":"Ein rücksichtsvoller Fahrer bremst rechtzeitig.","en":"A considerate driver brakes in good time.","ru":"Тактичный водитель тормозит вовремя.","vi":"Một người lái xe ân cần phanh đúng lúc.","fa":"یک راننده با ملاحظه به موقع ترمز می کند."}]},{"word":"der Rückspiegel","en":"rear-view mirror","ru":"зеркало заднего вида","vi":"gương chiếu hậu","fa":"the rearview mirror","examples":[{"de":"Bevor du losfährst, stell den Rückspiegel richtig ein.","en":"Before you set off, adjust the rear-view mirror properly.","ru":"Перед тем как тронуться, правильно отрегулируй зеркало заднего вида.","vi":"Trước khi lái xe, hãy điều chỉnh gương chiếu hậu cho chính xác.","fa":"قبل از حرکت، آینه عقب را به درستی تنظیم کنید."},{"de":"Im Rückspiegel sah ich, dass uns ein Polizeiauto folgte.","en":"In the rear-view mirror I saw that a police car was following us.","ru":"В зеркале заднего вида я увидел, что за нами едет полицейская машина.","vi":"Qua gương chiếu hậu, tôi thấy một chiếc xe cảnh sát đang đuổi theo chúng tôi.","fa":"در آینه عقب ماشین پلیس را دیدم که ما را تعقیب می کرد."},{"de":"Beim Abbiegen muss man immer in den Rückspiegel schauen.","en":"When turning you should always look in the rear-view mirror.","ru":"При повороте всегда нужно смотреть в зеркало заднего вида.","vi":"Khi rẽ, bạn luôn phải nhìn vào gương chiếu hậu.","fa":"هنگام چرخش، همیشه باید به آینه عقب نگاه کنید."}]},{"word":"rückwärts","en":"backwards","ru":"назад, задним ходом","vi":"ngược lại","fa":"به عقب","examples":[{"de":"Er fuhr rückwärts aus der Garage.","en":"He reversed out of the garage.","ru":"Он выехал задним ходом из гаража.","vi":"Anh ta lùi ra khỏi gara.","fa":"از گاراژ عقب رفت."},{"de":"Kannst du rückwärts bis zehn zählen?","en":"Can you count backwards to ten?","ru":"Можешь посчитать в обратном порядке до десяти?","vi":"Bạn có thể đếm ngược đến mười?","fa":"آیا می توانید تا ده برعکس بشمارید؟"},{"de":"Beim Einparken muss man oft rückwärts fahren.","en":"When parking you often have to reverse.","ru":"При парковке часто приходится сдавать назад.","vi":"Khi đỗ xe bạn thường phải lùi xe.","fa":"هنگام پارک کردن، اغلب مجبورید به عقب برگردید."}]},{"word":"das Rüebli","en":"carrot (Swiss German)","ru":"морковь (швейцарский немецкий)","vi":"củ cà rốt","fa":"هویج","examples":[{"de":"In der Schweiz sagt man Rüebli statt Karotte.","en":"In Switzerland people say 'Rüebli' instead of 'Karotte'.","ru":"В Швейцарии говорят «Rüebli» вместо «Karotte».","vi":"Ở Thụy Sĩ họ nói cà rốt thay vì cà rốt.","fa":"در سوئیس به جای هویج هویج می گویند."},{"de":"Zum Znacht gibt es Rüeblisuppe.","en":"For dinner there is carrot soup.","ru":"На ужин суп из моркови.","vi":"Bữa tối có súp cà rốt.","fa":"برای شام سوپ هویج وجود دارد."}]},{"word":"rufen","en":"to call; to shout","ru":"звать; кричать","vi":"gọi","fa":"تماس بگیرید","examples":[{"de":"Die Mutter ruft die Kinder zum Essen.","en":"The mother calls the children to eat.","ru":"Мать зовёт детей есть.","vi":"Mẹ gọi các con đi ăn.","fa":"مادر بچه ها را صدا می کند که غذا بخورند."},{"de":"Er rief laut um Hilfe.","en":"He shouted loudly for help.","ru":"Он громко звал на помощь.","vi":"Anh lớn tiếng kêu cứu.","fa":"با صدای بلند کمک خواست."}]},{"word":"die Rufnummer","en":"phone number","ru":"номер телефона","vi":"số điện thoại","fa":"شماره تلفن","examples":[{"de":"Bitte geben Sie Ihre Rufnummer für Rückfragen an.","en":"Please provide your phone number for any queries.","ru":"Укажите, пожалуйста, номер телефона на случай вопросов.","vi":"Vui lòng cung cấp số điện thoại của bạn cho bất kỳ thắc mắc.","fa":"لطفا برای هر گونه سوال شماره تلفن خود را وارد نمایید."},{"de":"Meine Rufnummer hat sich seit dem Umzug geändert.","en":"My phone number has changed since the move.","ru":"После переезда мой номер телефона изменился.","vi":"Số điện thoại của tôi đã thay đổi kể từ khi chuyển đi.","fa":"شماره تلفن من از زمان جابجایی تغییر کرده است."},{"de":"Notieren Sie sich bitte die Rufnummer des Kundendienstes.","en":"Please make a note of the customer service phone number.","ru":"Запишите, пожалуйста, номер телефона службы поддержки.","vi":"Vui lòng lưu ý số dịch vụ khách hàng.","fa":"لطفا به شماره خدمات مشتری توجه کنید."}]},{"word":"die Ruhe","en":"calm; quiet; rest","ru":"покой; тишина","vi":"sự bình tĩnh","fa":"آرامش","examples":[{"de":"Nach der Arbeit brauche ich etwas Ruhe.","en":"After work I need some rest.","ru":"После работы мне нужен покой.","vi":"Sau giờ làm việc tôi cần nghỉ ngơi.","fa":"بعد از کار به استراحت نیاز دارم."},{"de":"In der Bibliothek muss man Ruhe bewahren.","en":"You have to keep quiet in the library.","ru":"В библиотеке нужно соблюдать тишину.","vi":"You have to stay calm in the library.","fa":"شما باید در کتابخانه آرامش خود را حفظ کنید."}]},{"word":"rund","en":"round","ru":"круглый","vi":"tròn","fa":"گرد","examples":[{"de":"Der Tisch in der Küche ist rund.","en":"The table in the kitchen is round.","ru":"Стол на кухне круглый.","vi":"Der Tisch in der Küche ist rund.","fa":"میز آشپزخانه گرد است."},{"de":"Die Erde ist rund.","en":"The Earth is round.","ru":"Земля круглая.","vi":"Trái đất tròn.","fa":"زمین گرد است."}]},{"word":"die Runde","en":"round; lap","ru":"круг; раунд","vi":"vòng","fa":"دور","examples":[{"de":"Wir sind zwei Runden um den See gelaufen.","en":"We walked two laps around the lake.","ru":"Мы прошли два круга вокруг озера.","vi":"Chúng tôi đi dạo hai vòng quanh hồ.","fa":"دو دور دور دریاچه قدم زدیم."},{"de":"In der nächsten Runde spielen die besten zwei Teams gegeneinander.","en":"In the next round, the two best teams play against each other.","ru":"В следующем раунде две лучшие команды играют друг против друга.","vi":"Ở vòng tiếp theo, hai đội có thành tích tốt nhất sẽ đấu với nhau.","fa":"در دور بعد دو تیم برتر به مصاف یکدیگر می روند."}]},{"word":"runden","en":"to round (a number)","ru":"округлять (число)","vi":"tròn","fa":"گرد","examples":[{"de":"Wir sollen das Ergebnis auf zwei Stellen runden.","en":"We are supposed to round the result to two places.","ru":"Мы должны округлить результат до двух знаков.","vi":"Chúng ta nên làm tròn kết quả đến hai vị trí.","fa":"باید نتیجه را به دو مکان گرد کنیم."},{"de":"Runde die Zahl auf den nächsten Zehner.","en":"Round the number to the nearest ten.","ru":"Округли число до ближайшего десятка.","vi":"Làm tròn số đến số mười gần nhất.","fa":"عدد را به نزدیکترین ده گرد کنید."},{"de":"Wenn man rundet, geht etwas Genauigkeit verloren.","en":"When you round, some accuracy is lost.","ru":"При округлении теряется часть точности.","vi":"Khi bạn làm tròn, một số độ chính xác sẽ bị mất.","fa":"وقتی گرد می کنید، مقداری دقت از بین می رود."}]},{"word":"die Rundfahrt","en":"sightseeing tour","ru":"экскурсия (обзорная поездка)","vi":"chuyến tham quan","fa":"تور","examples":[{"de":"Wir machen morgen eine Rundfahrt durch die Altstadt.","en":"Tomorrow we are going on a sightseeing tour through the old town.","ru":"Завтра мы едем на экскурсию по старому городу.","vi":"Ngày mai chúng ta sẽ đi tham quan phố cổ.","fa":"فردا یه گشتی در شهر قدیمی میزنیم."},{"de":"Die Rundfahrt mit dem Bus dauert zwei Stunden.","en":"The bus tour takes two hours.","ru":"Экскурсия на автобусе длится два часа.","vi":"Chuyến tham quan bằng xe buýt mất hai giờ.","fa":"تور با اتوبوس دو ساعت طول می کشد."}]},{"word":"runterdrehen","en":"to turn down (heating, volume)","ru":"убавлять, делать тише/меньше (отопление, громкость)","vi":"từ chối","fa":"پایین بیاورند","examples":[{"de":"Kannst du bitte die Heizung runterdrehen?","en":"Can you turn the heating down, please?","ru":"Можешь убавить отопление, пожалуйста?","vi":"Bạn có thể vui lòng tắt lò sưởi được không?","fa":"میشه لطفا گرمایش رو کم کنید؟"},{"de":"Dreh die Musik etwas runter, es ist spät.","en":"Turn the music down a bit, it's late.","ru":"Сделай музыку потише, уже поздно.","vi":"Tắt nhạc đi một chút, muộn rồi.","fa":"یه کم موزیک رو کم کن دیر شده"},{"de":"Im Sommer drehe ich den Thermostat ganz runter.","en":"In summer I turn the thermostat right down.","ru":"Летом я убавляю термостат до минимума.","vi":"Vào mùa hè, tôi vặn máy điều nhiệt xuống hết cỡ.","fa":"در تابستان ترموستات را تا آخر پایین می‌آورم."}]},{"word":"runterfallen","en":"to fall down, drop","ru":"падать (вниз), ронять","vi":"ngã xuống","fa":"سقوط کردن","examples":[{"de":"Pass auf, dass das Glas nicht runterfällt!","en":"Be careful the glass doesn't fall down!","ru":"Осторожно, чтобы стакан не упал!","vi":"Hãy cẩn thận để không làm rơi kính!","fa":"مواظب باشید لیوان نیفتد!"},{"de":"Mir ist der Schlüssel runtergefallen.","en":"I dropped my key.","ru":"Я уронил ключ.","vi":"Tôi đánh rơi chìa khóa.","fa":"کلید را انداختم."},{"de":"Das Buch ist vom Regal runtergefallen.","en":"The book fell off the shelf.","ru":"Книга упала с полки.","vi":"Cuốn sách rơi khỏi kệ.","fa":"کتاب از قفسه افتاد."}]},{"word":"runterwerfen","en":"to throw down (colloquial)","ru":"сбрасывать, скидывать вниз","vi":"throw down","fa":"انداختن پایین","examples":[{"de":"Wirf mir bitte die Schlüssel vom Balkon runter!","en":"Please throw the keys down to me from the balcony!","ru":"Скинь мне, пожалуйста, ключи с балкона!","vi":"Hãy ném cho tôi chìa khóa từ ban công!","fa":"لطفا کلیدها را از بالکن به من بیندازید!"},{"de":"Er hat seine Tasche einfach auf den Boden runtergeworfen.","en":"He just threw his bag down on the floor.","ru":"Он просто швырнул свою сумку на пол.","vi":"Anh ta vừa ném chiếc túi của mình xuống đất.","fa":"فقط کیفش را روی زمین انداخت."}]},{"word":"rutschen","en":"to slip, slide","ru":"скользить, поскальзываться","vi":"trượt","fa":"اسلاید","examples":[{"de":"Vorsicht, der Boden ist nass und du kannst rutschen.","en":"Careful, the floor is wet and you could slip.","ru":"Осторожно, пол мокрый, можно поскользнуться.","vi":"Hãy cẩn thận, sàn ướt và bạn có thể trượt.","fa":"مراقب باشید، زمین خیس است و ممکن است لیز بخورید."},{"de":"Das Auto ist auf dem Eis gerutscht.","en":"The car slid on the ice.","ru":"Машину занесло на льду.","vi":"Chiếc xe trượt trên băng.","fa":"ماشین روی یخ لیز خورد."},{"de":"Die Kinder rutschen gern auf der Rutsche.","en":"The children love sliding down the slide.","ru":"Дети обожают кататься с горки.","vi":"Trẻ em thích thú trượt trên cầu trượt.","fa":"بچه ها از سر خوردن روی سرسره لذت می برند."}]},{"word":"der Saal","en":"hall","ru":"зал","vi":"hội trường","fa":"سالن","examples":[{"de":"Die Konferenz findet im großen Saal statt.","en":"The conference takes place in the large hall.","ru":"Конференция проходит в большом зале.","vi":"Die Konferenz đã tìm thấy điều tuyệt vời nhất về Saal.","fa":"کنفرانس در سالن بزرگ برگزار می شود."},{"de":"Der Saal war bis auf den letzten Platz gefüllt.","en":"The hall was filled to the last seat.","ru":"Зал был заполнен до последнего места.","vi":"Der Saal war bis auf den letzten Platz gefüllt.","fa":"ظرفیت سالن پر شد."}]},{"word":"die Sache","en":"thing; matter","ru":"вещь; дело","vi":"điều đó","fa":"چیز","examples":[{"de":"Das ist eine wichtige Sache für mich.","en":"This is an important matter for me.","ru":"Это важное дело для меня.","vi":"Đây là một điều quan trọng đối với tôi.","fa":"این برای من یک چیز مهم است."},{"de":"Pack deine Sachen zusammen, wir müssen los.","en":"Pack your things together, we have to go.","ru":"Собери свои вещи, нам пора идти.","vi":"Hãy thu dọn đồ đạc của bạn, chúng ta phải đi.","fa":"وسایلت را جمع کن، باید برویم."}]},{"word":"der Sachschaden","en":"property damage, material damage","ru":"материальный ущерб, имущественный вред","vi":"thiệt hại tài sản","fa":"خسارت مالی","examples":[{"de":"Bei dem Unfall gab es nur Sachschaden, niemand wurde verletzt.","en":"In the accident there was only property damage; nobody was injured.","ru":"В аварии был только материальный ущерб; никто не пострадал.","vi":"Vụ tai nạn chỉ gây thiệt hại về tài sản và không có ai bị thương.","fa":"این حادثه تنها خسارت مالی به بار آورد و به کسی آسیب نرسید."},{"de":"Der Sachschaden durch das Feuer war sehr hoch.","en":"The property damage caused by the fire was very high.","ru":"Материальный ущерб от пожара был очень большим.","vi":"Thiệt hại về tài sản do vụ cháy gây ra là rất lớn.","fa":"خسارت مالی ناشی از آتش سوزی بسیار زیاد بود."},{"de":"Die Versicherung bezahlt den entstandenen Sachschaden.","en":"The insurance pays for the property damage that occurred.","ru":"Страховая компания возмещает причинённый материальный ущерб.","vi":"Bảo hiểm sẽ thanh toán các thiệt hại về tài sản phát sinh.","fa":"بیمه خسارت مالی ناشی از آن را پرداخت می کند."}]},{"word":"der Sack","en":"sack; bag","ru":"мешок","vi":"cái túi","fa":"کیف","examples":[{"de":"Er trägt einen Sack Kartoffeln in den Keller.","en":"He carries a sack of potatoes into the cellar.","ru":"Он несёт мешок картошки в подвал.","vi":"Anh ta mang một bao khoai tây vào hầm.","fa":"او یک گونی سیب زمینی را به داخل سرداب می برد."},{"de":"Der Müll ist im Sack vor der Tür.","en":"The trash is in the bag in front of the door.","ru":"Мусор в мешке перед дверью.","vi":"Rác nằm trong túi trước cửa.","fa":"زباله ها در کیسه جلوی در هستند."}]},{"word":"der Saft","en":"juice","ru":"сок","vi":"nước trái cây","fa":"آب میوه","examples":[{"de":"Zum Frühstück trinke ich immer einen Saft.","en":"For breakfast I always drink a juice.","ru":"На завтрак я всегда пью сок.","vi":"Tôi luôn uống nước trái cây vào bữa sáng.","fa":"من همیشه برای صبحانه یک آب میوه می خورم."},{"de":"Dieser Apfelsaft schmeckt sehr frisch.","en":"This apple juice tastes very fresh.","ru":"Этот яблочный сок очень свежий на вкус.","vi":"Nước táo này có vị rất tươi.","fa":"این آب سیب طعم بسیار تازه ای دارد."}]},{"word":"die Säge","en":"saw (tool)","ru":"пила (инструмент)","vi":"cái cưa","fa":"اره","examples":[{"de":"Mit der Säge schnitt er das Brett in zwei Teile.","en":"With the saw he cut the board into two pieces.","ru":"Пилой он распилил доску на две части.","vi":"Anh ta dùng cưa cắt tấm ván thành hai mảnh.","fa":"او با استفاده از اره تخته را به دو قسمت تقسیم کرد."},{"de":"Die Säge ist nicht mehr scharf genug.","en":"The saw is no longer sharp enough.","ru":"Пила уже недостаточно острая.","vi":"Cái cưa không còn đủ sắc bén nữa.","fa":"اره دیگر به اندازه کافی تیز نیست."},{"de":"Im Schuppen hängt eine alte Säge an der Wand.","en":"In the shed there is an old saw hanging on the wall.","ru":"В сарае на стене висит старая пила.","vi":"Một chiếc cưa cũ treo trên tường trong nhà kho.","fa":"یک اره قدیمی در آلونک به دیوار آویزان است."}]},{"word":"sagen","en":"to say","ru":"говорить; сказать","vi":"nói","fa":"بگو","examples":[{"de":"Kannst du mir sagen, wie spät es ist?","en":"Can you tell me what time it is?","ru":"Можешь сказать мне, который час?","vi":"Bạn có thể cho tôi biết bây giờ là mấy giờ không?","fa":"میشه بگی ساعت چنده؟"},{"de":"Er hat nichts dazu gesagt.","en":"He didn't say anything about it.","ru":"Он ничего не сказал по этому поводу.","vi":"Anh ấy không nói gì về chuyện đó.","fa":"او چیزی در این مورد نگفت."}]},{"word":"die Saison","en":"season","ru":"сезон","vi":"mùa giải","fa":"فصل","examples":[{"de":"Im Sommer ist die Hauptsaison für Touristen.","en":"Summer is the main tourist season.","ru":"Лето — основной туристический сезон.","vi":"Mùa hè là mùa cao điểm của khách du lịch.","fa":"تابستان فصل اوج گردشگران است."},{"de":"Diese Früchte gibt es nur in der Saison.","en":"These fruits are only available in season.","ru":"Эти фрукты бывают только в сезон.","vi":"Những loại trái cây này chỉ có theo mùa.","fa":"این میوه ها فقط در فصل در دسترس هستند."}]},{"word":"der Salat","en":"salad; lettuce","ru":"салат","vi":"món salad","fa":"سالاد","examples":[{"de":"Ich hätte gern einen gemischten Salat.","en":"I would like a mixed salad.","ru":"Я бы хотел смешанный салат.","vi":"Tôi muốn một món salad trộn.","fa":"من یک سالاد مخلوط می خواهم."},{"de":"Im Garten wächst frischer Salat.","en":"Fresh lettuce is growing in the garden.","ru":"В саду растёт свежий салат.","vi":"Rau diếp tươi mọc trong vườn.","fa":"کاهوی تازه در باغ می روید."}]},{"word":"die Salbe","en":"ointment","ru":"мазь","vi":"thuốc mỡ","fa":"پماد","examples":[{"de":"Trag die Salbe zweimal täglich auf die Wunde auf.","en":"Apply the ointment to the wound twice a day.","ru":"Наноси мазь на рану дважды в день.","vi":"Bôi thuốc mỡ lên vết thương hai lần mỗi ngày.","fa":"پماد را دو بار در روز روی زخم بمالید."},{"de":"Der Arzt hat mir eine Salbe gegen die Schmerzen verschrieben.","en":"The doctor prescribed me an ointment for the pain.","ru":"Врач прописал мне мазь от боли.","vi":"Bác sĩ kê cho tôi một loại thuốc mỡ để giảm đau.","fa":"دکتر برای من پماد برای درد تجویز کرد."}]},{"word":"der Salon","en":"salon","ru":"салон","vi":"thẩm mỹ viện","fa":"سالن","examples":[{"de":"Sie lässt sich die Haare im Salon schneiden.","en":"She has her hair cut at the salon.","ru":"Она стрижётся в салоне.","vi":"Cô ấy cắt tóc ở tiệm.","fa":"او موهایش را در سالن کوتاه می کند."},{"de":"In der Stadt gibt es einen neuen Schönheitssalon.","en":"There is a new beauty salon in the city.","ru":"В городе открылся новый салон красоты.","vi":"Có một thẩm mỹ viện mới trong thị trấn.","fa":"یک سالن زیبایی جدید در شهر وجود دارد."}]},{"word":"die Salsa","en":"salsa (dance)","ru":"сальса (танец)","vi":"salsa","fa":"سالسا","examples":[{"de":"Die Salsa ist ein lebhafter Tanz aus Lateinamerika.","en":"Salsa is a lively dance from Latin America.","ru":"Сальса — это зажигательный танец из Латинской Америки.","vi":"Salsa là một điệu nhảy sôi động của Mỹ Latinh.","fa":"سالسا یک رقص پر جنب و جوش از آمریکای لاتین است."},{"de":"Jeden Freitag gibt es im Club eine Salsa-Party.","en":"Every Friday there is a salsa party at the club.","ru":"Каждую пятницу в клубе проходит вечеринка сальсы.","vi":"Thứ sáu hàng tuần có một bữa tiệc salsa trong câu lạc bộ.","fa":"هر جمعه یک مهمانی سالسا در باشگاه برگزار می شود."},{"de":"Bei der Salsa bewegt man die Hüften viel.","en":"In salsa you move your hips a lot.","ru":"В сальсе много движений бёдрами.","vi":"Salsa liên quan đến việc di chuyển hông của bạn rất nhiều.","fa":"سالسا شامل حرکت زیاد باسن است."}]},{"word":"das Salz","en":"salt","ru":"соль","vi":"muối","fa":"نمک","examples":[{"de":"Die Suppe braucht noch etwas Salz.","en":"The soup needs a bit more salt.","ru":"Супу нужно ещё немного соли.","vi":"Súp vẫn cần một chút muối.","fa":"سوپ همچنان به نمک کمی نیاز دارد."},{"de":"Bitte reich mir das Salz.","en":"Please pass me the salt.","ru":"Пожалуйста, передай мне соль.","vi":"Làm ơn đưa cho tôi muối.","fa":"لطفا نمک را به من بدهید"}]},{"word":"salzig","en":"salty","ru":"солёный","vi":"mặn","fa":"شور","examples":[{"de":"Die Suppe ist mir zu salzig.","en":"The soup is too salty for me.","ru":"Суп для меня слишком солёный.","vi":"Súp quá mặn đối với tôi.","fa":"سوپ برای من خیلی شور است."},{"de":"Das Meerwasser schmeckt salzig.","en":"Sea water tastes salty.","ru":"Морская вода на вкус солёная.","vi":"Nước biển có vị mặn.","fa":"آب دریا مزه شوری دارد."},{"de":"Ich esse lieber salzige als süße Snacks.","en":"I prefer salty snacks to sweet ones.","ru":"Солёные закуски я предпочитаю сладким.","vi":"Tôi thích ăn đồ ăn mặn hơn đồ ngọt.","fa":"من خوردن تنقلات شور را به شیرینی ترجیح می دهم."}]},{"word":"sammeln","en":"to collect","ru":"собирать","vi":"thu thập","fa":"جمع آوری کنید","examples":[{"de":"Als Kind habe ich Briefmarken gesammelt.","en":"As a child I collected stamps.","ru":"В детстве я собирал марки.","vi":"Tôi đã sưu tập tem khi còn nhỏ.","fa":"از بچگی تمبر جمع می کردم."},{"de":"Wir sammeln Geld für einen guten Zweck.","en":"We are collecting money for a good cause.","ru":"Мы собираем деньги на доброе дело.","vi":"Chúng tôi đang thu tiền vì một lý do chính đáng.","fa":"ما برای یک هدف خوب پول جمع می کنیم."}]},{"word":"sämtlich","en":"all; entire","ru":"все, всё, целиком","vi":"tất cả bọn họ","fa":"همه آنها","examples":[{"de":"Sämtliche Unterlagen liegen auf dem Schreibtisch.","en":"All the documents are on the desk.","ru":"Все документы лежат на письменном столе.","vi":"Tất cả tài liệu đều ở trên bàn.","fa":"تمام مدارک روی میز است."},{"de":"Er hat sämtliche Bücher des Autors gelesen.","en":"He has read all of the author's books.","ru":"Он прочитал все книги этого автора.","vi":"Anh ấy đã đọc tất cả sách của tác giả.","fa":"او تمام کتاب های نویسنده را خوانده است."},{"de":"Sämtliche Teilnehmer haben die Prüfung bestanden.","en":"All the participants passed the exam.","ru":"Все участники сдали экзамен.","vi":"Tất cả những người tham gia đã vượt qua kỳ thi.","fa":"همه شرکت کنندگان در آزمون موفق شدند."}]},{"word":"sämtliche","en":"all; entire","ru":"все; весь","vi":"tất cả","fa":"همه","examples":[{"de":"Er hat sämtliche Bücher aus dem Regal genommen.","en":"He took all the books off the shelf.","ru":"Он взял все книги с полки.","vi":"Anh ấy lấy tất cả sách ra khỏi kệ.","fa":"همه کتاب ها را از قفسه برداشت."},{"de":"Sämtliche Mitarbeiter wurden über die Änderung informiert.","en":"All employees were informed about the change.","ru":"Все сотрудники были проинформированы об изменении.","vi":"Tất cả nhân viên đã được thông báo về sự thay đổi.","fa":"همه کارکنان در مورد تغییر مطلع شدند."}]},{"word":"der Sand","en":"sand","ru":"песок","vi":"cát","fa":"شن و ماسه","examples":[{"de":"Die Kinder spielen am Strand im Sand.","en":"The children are playing in the sand on the beach.","ru":"Дети играют в песке на пляже.","vi":"Những đứa trẻ đang chơi đùa trên bãi cát trên bãi biển.","fa":"بچه ها در شن های ساحل بازی می کنند."},{"de":"Der Wind wehte den Sand in unsere Augen.","en":"The wind blew sand into our eyes.","ru":"Ветер задувал песок нам в глаза.","vi":"Gió thổi cát bay vào mắt chúng tôi.","fa":"باد شن ها را در چشمانمان فرو برد."}]},{"word":"der Sänger","en":"singer","ru":"певец","vi":"ca sĩ","fa":"خواننده","examples":[{"de":"Der Sänger begeisterte das Publikum.","en":"The singer thrilled the audience.","ru":"Певец привёл публику в восторг.","vi":"Nam ca sĩ khiến khán giả thích thú.","fa":"این خواننده حضار را به وجد آورد."},{"de":"Sie ist eine bekannte Sängerin aus Österreich.","en":"She is a well-known singer from Austria.","ru":"Она известная певица из Австрии.","vi":"Cô là một ca sĩ nổi tiếng đến từ Áo.","fa":"او یک خواننده سرشناس اهل اتریش است."}]},{"word":"die Sängerin","en":"singer (female)","ru":"певица","vi":"ca sĩ","fa":"خواننده","examples":[{"de":"Die Sängerin trat zum ersten Mal in dieser Stadt auf.","en":"The singer performed in this city for the first time.","ru":"Певица впервые выступила в этом городе.","vi":"Ca sĩ lần đầu tiên biểu diễn tại thành phố này.","fa":"این خواننده برای اولین بار در این شهر اجرا داشت."},{"de":"Sie möchte später eine berühmte Sängerin werden.","en":"She wants to become a famous singer one day.","ru":"Она хочет когда-нибудь стать знаменитой певицей.","vi":"Cô muốn trở thành một ca sĩ nổi tiếng khi lớn lên.","fa":"او می خواهد وقتی بزرگ شد خواننده مشهوری شود."},{"de":"Die junge Sängerin gewann den ersten Preis.","en":"The young singer won first prize.","ru":"Молодая певица получила первый приз.","vi":"Ca sĩ trẻ đoạt giải nhất.","fa":"این خواننده جوان برنده جایزه اول شد."}]},{"word":"satt","en":"full (not hungry)","ru":"сытый","vi":"no (không đói)","fa":"سیر","examples":[{"de":"Danke, ich bin satt.","en":"Thanks, I'm full.","ru":"Спасибо, я сыт.","vi":"Cảm ơn, tôi no rồi.","fa":"ممنون من سیر شدم"},{"de":"Nach dem großen Essen waren alle satt.","en":"After the big meal everyone was full.","ru":"После обильной еды все были сыты.","vi":"Sau bữa ăn thịnh soạn, mọi người đều no nê.","fa":"بعد از غذای بزرگ همه سیر شدند."}]},{"word":"der Satz","en":"sentence","ru":"предложение (грамм.)","vi":"câu","fa":"جمله","examples":[{"de":"Bitte bilden Sie einen Satz mit diesem Wort.","en":"Please form a sentence with this word.","ru":"Пожалуйста, составьте предложение с этим словом.","vi":"Hãy đặt câu với từ này.","fa":"لطفا با این کلمه یک جمله بسازید."},{"de":"Dieser Satz ist grammatisch nicht richtig.","en":"This sentence is not grammatically correct.","ru":"Это предложение грамматически неправильное.","vi":"Câu này sai ngữ pháp.","fa":"این جمله از نظر گرامری نادرست است."}]},{"word":"sauber","en":"clean","ru":"чистый","vi":"sạch sẽ","fa":"تمیز کردن","examples":[{"de":"Die Küche ist wieder sauber.","en":"The kitchen is clean again.","ru":"Кухня снова чистая.","vi":"Nhà bếp sạch sẽ trở lại.","fa":"آشپزخانه دوباره تمیز است."},{"de":"Zieh bitte saubere Kleidung an.","en":"Please put on clean clothes.","ru":"Пожалуйста, надень чистую одежду.","vi":"Hãy mặc quần áo sạch sẽ.","fa":"لطفا لباس تمیز بپوشید"}]},{"word":"die Sauce","en":"sauce, gravy","ru":"соус, подливка","vi":"nước sốt","fa":"سس","examples":[{"de":"Zu den Nudeln gab es eine leckere Sauce mit Tomaten.","en":"There was a tasty sauce with tomatoes to go with the pasta.","ru":"К пасте был вкусный соус с помидорами.","vi":"Mì ống được phục vụ với nước sốt cà chua thơm ngon.","fa":"پاستا با سس گوجه فرنگی خوشمزه سرو شد."},{"de":"Die Sauce ist mir leider etwas zu salzig.","en":"The sauce is unfortunately a bit too salty for me.","ru":"Соус, к сожалению, для меня немного пересоленный.","vi":"Thật không may, nước sốt hơi mặn đối với tôi.","fa":"متاسفانه سس برای من کمی شور است."},{"de":"Sie rührte die Sauce, damit sie nicht anbrennt.","en":"She stirred the sauce so that it wouldn't burn.","ru":"Она помешивала соус, чтобы он не пригорел.","vi":"Cô khuấy nước sốt để nó không bị cháy.","fa":"سس را هم زد تا نسوزد."}]},{"word":"sauer","en":"sour; angry (informal)","ru":"кислый; сердитый (разг.)","vi":"chua","fa":"ترش","examples":[{"de":"Die Zitrone schmeckt sehr sauer.","en":"The lemon tastes very sour.","ru":"Лимон очень кислый на вкус.","vi":"chanh có vị rất chua.","fa":"طعم لیمو بسیار ترش است."},{"de":"Sie war sauer, weil er zu spät kam.","en":"She was annoyed because he came too late.","ru":"Она разозлилась, потому что он опоздал.","vi":"Cô tức giận vì anh đến muộn.","fa":"او عصبانی بود زیرا او دیر کرده بود."}]},{"word":"die Schachtel","en":"box","ru":"коробка; пачка","vi":"cái hộp","fa":"جعبه","examples":[{"de":"Er raucht eine Schachtel Zigaretten am Tag.","en":"He smokes a pack of cigarettes a day.","ru":"Он выкуривает пачку сигарет в день.","vi":"Anh ấy hút một gói thuốc lá mỗi ngày.","fa":"او روزی یک پاکت سیگار می کشد."},{"de":"Die Schokolade liegt in einer bunten Schachtel.","en":"The chocolate is in a colorful box.","ru":"Шоколад лежит в яркой коробке.","vi":"Sô cô la được đựng trong một chiếc hộp đầy màu sắc.","fa":"شکلات در یک جعبه رنگارنگ است."}]},{"word":"schade","en":"a pity; too bad","ru":"жаль","vi":"quá tệ","fa":"خیلی بد","examples":[{"de":"Schade, dass du nicht kommen kannst.","en":"It's a pity that you can't come.","ru":"Жаль, что ты не можешь прийти.","vi":"Thật tiếc là bạn không thể đến được.","fa":"حیف که نمیتونی بیای"},{"de":"Es wäre schade, das Konzert zu verpassen.","en":"It would be a shame to miss the concert.","ru":"Было бы жаль пропустить концерт.","vi":"Sẽ thật đáng tiếc nếu bỏ lỡ buổi hòa nhạc.","fa":"حیف است که کنسرت را از دست بدهیم."}]},{"word":"schaden","en":"to harm; to damage","ru":"вредить","vi":"làm hại","fa":"آسیب","examples":[{"de":"Rauchen schadet der Gesundheit.","en":"Smoking is harmful to your health.","ru":"Курение вредит здоровью.","vi":"Hút thuốc có hại cho sức khỏe của bạn.","fa":"سیگار برای سلامتی مضر است."},{"de":"Ein bisschen Bewegung schadet nie.","en":"A bit of exercise never hurts.","ru":"Немного физической активности никогда не помешает.","vi":"Một bài tập nhỏ không bao giờ đau.","fa":"کمی ورزش هرگز ضرری ندارد."}]},{"word":"schadenfrei","en":"claim-free, with no accidents (insurance)","ru":"безаварийный, без страховых случаев (страхование)","vi":"không có thiệt hại","fa":"بدون آسیب","examples":[{"de":"Ich fahre seit zehn Jahren schadenfrei.","en":"I've been driving claim-free for ten years.","ru":"Я езжу без аварий уже десять лет.","vi":"Tôi đã lái xe không bị hư hại trong mười năm.","fa":"ده سال است که بدون آسیب رانندگی می کنم."},{"de":"Wer schadenfrei bleibt, zahlt weniger für die Versicherung.","en":"Whoever stays claim-free pays less for insurance.","ru":"Кто ездит без страховых случаев, платит меньше за страховку.","vi":"Những người không có yêu cầu bồi thường sẽ phải trả ít tiền bảo hiểm hơn.","fa":"کسانی که بدون ادعا می مانند هزینه بیمه کمتری می پردازند."},{"de":"Nach mehreren schadenfreien Jahren sank mein Beitrag.","en":"After several claim-free years my premium dropped.","ru":"После нескольких безаварийных лет моя премия снизилась.","vi":"Sau vài năm không có yêu cầu bồi thường, phí bảo hiểm của tôi đã giảm.","fa":"پس از چندین سال بدون ادعا، حق بیمه من کاهش یافت."}]},{"word":"der Schadensfall","en":"insurance claim; case of damage","ru":"страховой случай; случай причинения ущерба","vi":"sự kiện thiệt hại","fa":"رویداد آسیب","examples":[{"de":"Im Schadensfall rufen Sie bitte die Hotline an.","en":"In the event of a claim, please call the hotline.","ru":"В случае страхового события, пожалуйста, позвоните на горячую линию.","vi":"Khi có hư hỏng vui lòng gọi tới đường dây nóng.","fa":"در صورت آسیب لطفا با خط تلفن تماس بگیرید."},{"de":"Die Versicherung prüft jeden Schadensfall genau.","en":"The insurance examines every claim carefully.","ru":"Страховая компания тщательно проверяет каждый страховой случай.","vi":"Công ty bảo hiểm kiểm tra mọi trường hợp thiệt hại một cách cẩn thận.","fa":"شرکت بیمه هر مورد خسارت را به دقت بررسی می کند."},{"de":"Bei einem Schadensfall brauchen Sie alle Belege.","en":"In the case of damage you need all the receipts.","ru":"При страховом случае вам нужны все чеки.","vi":"Trong trường hợp có thiệt hại, bạn sẽ cần tất cả bằng chứng.","fa":"در صورت آسیب، به تمام شواهد نیاز خواهید داشت."}]},{"word":"der Schadenshergang","en":"sequence of events of an accident; course of the damage","ru":"обстоятельства произошедшего; ход событий (аварии, ущерба)","vi":"quá trình thiệt hại","fa":"سیر آسیب","examples":[{"de":"Bitte beschreiben Sie den Schadenshergang genau.","en":"Please describe exactly how the damage occurred.","ru":"Пожалуйста, опишите точно, как произошёл ущерб.","vi":"Hãy mô tả chi tiết nguyên nhân hư hỏng.","fa":"لطفا علت آسیب را به طور کامل توضیح دهید."},{"de":"Der Schadenshergang ist auf dem Formular einzutragen.","en":"The course of the accident must be entered on the form.","ru":"Обстоятельства аварии нужно внести в бланк.","vi":"Nguyên nhân gây ra thiệt hại phải được ghi vào biểu mẫu.","fa":"علت خسارت باید در فرم درج شود."},{"de":"Die Polizei dokumentierte den ganzen Schadenshergang.","en":"The police documented the entire course of events.","ru":"Полиция задокументировала весь ход событий.","vi":"Cảnh sát đã ghi nhận toàn bộ thiệt hại.","fa":"پلیس کل خسارت را مستند کرد."}]},{"word":"schädigen","en":"to damage, to harm","ru":"наносить вред, повреждать, портить","vi":"thiệt hại","fa":"آسیب","examples":[{"de":"Rauchen schädigt die Gesundheit.","en":"Smoking damages your health.","ru":"Курение вредит здоровью.","vi":"Hút thuốc làm tổn hại sức khỏe của bạn.","fa":"سیگار به سلامتی شما آسیب می رساند."},{"de":"Der Skandal hat das Ansehen der Firma schwer geschädigt.","en":"The scandal severely damaged the company's reputation.","ru":"Скандал сильно повредил репутации компании.","vi":"Vụ bê bối đã làm tổn hại nghiêm trọng đến danh tiếng của công ty.","fa":"این رسوایی به شدت به اعتبار شرکت لطمه زد."},{"de":"Abgase schädigen die Umwelt.","en":"Exhaust fumes harm the environment.","ru":"Выхлопные газы вредят окружающей среде.","vi":"Khí thải gây ô nhiễm môi trường.","fa":"دود اگزوز به محیط زیست آسیب می رساند."}]},{"word":"der Schadstoff","en":"pollutant, harmful substance","ru":"вредное вещество, загрязнитель","vi":"chất gây ô nhiễm","fa":"آلاینده","examples":[{"de":"Autos stoßen viele Schadstoffe in die Luft aus.","en":"Cars emit many pollutants into the air.","ru":"Автомобили выбрасывают в воздух много вредных веществ.","vi":"Ô tô thải ra rất nhiều chất ô nhiễm vào không khí.","fa":"خودروها آلاینده های زیادی را در هوا منتشر می کنند."},{"de":"Die Schadstoffe gelangen über die Flüsse ins Meer.","en":"The pollutants reach the sea via the rivers.","ru":"Вредные вещества попадают в море через реки.","vi":"Các chất ô nhiễm lan ra biển qua sông.","fa":"آلاینده ها از طریق رودخانه ها به دریا می رسند."},{"de":"Filter sollen die Menge der Schadstoffe verringern.","en":"Filters are meant to reduce the amount of pollutants.","ru":"Фильтры должны снизить количество вредных веществ.","vi":"Bộ lọc nhằm mục đích giảm lượng chất ô nhiễm.","fa":"فیلترها برای کاهش میزان آلاینده ها در نظر گرفته شده اند."}]},{"word":"schaffen","en":"to manage; to accomplish","ru":"успевать; справляться","vi":"tạo ra","fa":"ایجاد کنید","examples":[{"de":"Ich glaube, wir schaffen den Zug noch.","en":"I think we can still catch the train.","ru":"Я думаю, мы ещё успеем на поезд.","vi":"Tôi nghĩ chúng ta vẫn có thể di chuyển được.","fa":"فکر می کنم هنوز هم می توانیم حرکت کنیم."},{"de":"Sie hat die Prüfung mit Bravour geschafft.","en":"She passed the exam with flying colors.","ru":"Она блестяще сдала экзамен.","vi":"Cô đã vượt qua kỳ thi với thành tích xuất sắc.","fa":"او امتحان را با رنگ آمیزی پشت سر گذاشت."}]},{"word":"schälen","en":"to peel","ru":"чистить (кожуру), очищать","vi":"bóc vỏ","fa":"پوست کندن","examples":[{"de":"Schäl die Kartoffeln, bevor du sie kochst.","en":"Peel the potatoes before you boil them.","ru":"Почисти картофель, прежде чем варить его.","vi":"Gọt vỏ khoai tây trước khi nấu.","fa":"سیب زمینی ها را قبل از پختن پوست بگیرید."},{"de":"Kannst du bitte die Äpfel für den Kuchen schälen?","en":"Can you peel the apples for the cake, please?","ru":"Можешь, пожалуйста, почистить яблоки для пирога?","vi":"Bạn có thể gọt táo để làm bánh được không?","fa":"میشه لطفا سیب های کیک رو پوست بگیرید؟"},{"de":"Mit diesem Gerät lässt sich Gemüse schnell schälen.","en":"With this tool vegetables can be peeled quickly.","ru":"Этим прибором овощи можно быстро чистить.","vi":"Thiết bị này cho phép bạn gọt vỏ rau củ một cách nhanh chóng.","fa":"این دستگاه به شما این امکان را می دهد که سبزیجات را به سرعت پوست بگیرید."}]},{"word":"schalten","en":"to switch; to shift (gears)","ru":"переключать","vi":"chuyển đổi","fa":"سوئیچ","examples":[{"de":"Er muss beim Autofahren oft schalten.","en":"He often has to shift gears while driving.","ru":"Ему часто приходится переключать передачи во время вождения.","vi":"Anh ấy thường xuyên phải sang số khi lái xe.","fa":"او اغلب باید هنگام رانندگی دنده را عوض کند."},{"de":"Bitte schalte das Licht aus, wenn du gehst.","en":"Please switch off the light when you leave.","ru":"Пожалуйста, выключи свет, когда уйдёшь.","vi":"Vui lòng tắt đèn khi bạn rời đi.","fa":"لطفاً هنگام خروج چراغ ها را خاموش کنید."}]},{"word":"die Schaltfläche","en":"button (on screen)","ru":"кнопка (на экране)","vi":"cái nút","fa":"دکمه","examples":[{"de":"Klicke auf die grüne Schaltfläche, um zu speichern.","en":"Click the green button to save.","ru":"Нажми на зелёную кнопку, чтобы сохранить.","vi":"Nhấp vào nút màu xanh lá cây để lưu.","fa":"برای ذخیره روی دکمه سبز رنگ کلیک کنید."},{"de":"Die Schaltfläche zum Abbrechen ist unten rechts.","en":"The cancel button is at the bottom right.","ru":"Кнопка отмены находится внизу справа.","vi":"Nút hủy ở phía dưới bên phải.","fa":"دکمه لغو در پایین سمت راست قرار دارد."},{"de":"Wenn du auf diese Schaltfläche tippst, beginnt der Download.","en":"If you tap this button, the download begins.","ru":"Если ты нажмёшь на эту кнопку, начнётся загрузка.","vi":"Khi bạn nhấn vào nút này, quá trình tải xuống sẽ bắt đầu.","fa":"با زدن این دکمه دانلود شروع می شود."}]},{"word":"scharf","en":"sharp; spicy","ru":"острый","vi":"nhọn","fa":"تیز","examples":[{"de":"Das Messer ist sehr scharf.","en":"The knife is very sharp.","ru":"Нож очень острый.","vi":"Con dao rất sắc.","fa":"چاقو بسیار تیز است."},{"de":"Mir ist das Essen zu scharf.","en":"The food is too spicy for me.","ru":"Еда для меня слишком острая.","vi":"Thức ăn quá cay đối với tôi.","fa":"غذا برای من خیلی تند است."}]},{"word":"der Schatten","en":"shadow; shade","ru":"тень","vi":"cái bóng","fa":"سایه","examples":[{"de":"Wir setzen uns lieber in den Schatten.","en":"We prefer to sit in the shade.","ru":"Мы лучше сядем в тень.","vi":"Chúng tôi thích ngồi trong bóng râm hơn.","fa":"ما ترجیح می دهیم در سایه بنشینیم."},{"de":"Der Baum wirft einen langen Schatten.","en":"The tree casts a long shadow.","ru":"Дерево отбрасывает длинную тень.","vi":"Cây đổ bóng dài.","fa":"درخت سایه بلندی می اندازد."}]},{"word":"schätzen","en":"to estimate; to appreciate","ru":"оценивать; ценить","vi":"đánh giá cao","fa":"قدردانی","examples":[{"de":"Ich schätze sein Alter auf etwa vierzig Jahre.","en":"I estimate his age to be about forty years.","ru":"Я оцениваю его возраст примерно в сорок лет.","vi":"Tôi ước chừng tuổi của anh ấy khoảng bốn mươi tuổi.","fa":"سن او را حدود چهل سال تخمین می زنم."},{"de":"Ich schätze deine Hilfe sehr.","en":"I really appreciate your help.","ru":"Я очень ценю твою помощь.","vi":"Tôi thực sự đánh giá cao sự giúp đỡ của bạn.","fa":"من واقعا از کمک شما قدردانی می کنم."}]},{"word":"schauen","en":"to look","ru":"смотреть","vi":"nhìn","fa":"نگاه کن","examples":[{"de":"Schau mal, wie schön der Sonnenuntergang ist!","en":"Look how beautiful the sunset is!","ru":"Смотри, какой красивый закат!","vi":"Hãy nhìn hoàng hôn đẹp làm sao!","fa":"ببین غروب چقدر زیباست"},{"de":"Er schaut jeden Abend die Nachrichten.","en":"He watches the news every evening.","ru":"Он каждый вечер смотрит новости.","vi":"Anh ấy xem tin tức mỗi tối.","fa":"او هر روز عصر اخبار را تماشا می کند."}]},{"word":"schaufeln","en":"to shovel, dig","ru":"копать лопатой, чистить (снег)","vi":"xẻng","fa":"بیل","examples":[{"de":"Im Winter müssen wir oft Schnee schaufeln.","en":"In winter we often have to shovel snow.","ru":"Зимой нам часто приходится чистить снег.","vi":"Vào mùa đông chúng ta thường phải xúc tuyết.","fa":"در زمستان اغلب مجبوریم برف را پارو کنیم."},{"de":"Er schaufelte ein Loch für den neuen Baum.","en":"He dug a hole for the new tree.","ru":"Он выкопал яму для нового дерева.","vi":"Anh ta đào một cái hố cho cây mới.","fa":"او سوراخی برای درخت جدید کند."},{"de":"Die Arbeiter schaufeln Sand auf den Lastwagen.","en":"The workers are shovelling sand onto the lorry.","ru":"Рабочие грузят песок на грузовик.","vi":"Các công nhân đang xúc cát lên xe tải.","fa":"کارگران ماسه را روی کامیون بیل می کنند."}]},{"word":"das Schaufenster","en":"shop window","ru":"витрина (магазина)","vi":"cửa sổ cửa hàng","fa":"ویترین مغازه","examples":[{"de":"Im Schaufenster steht ein schönes Kleid.","en":"There is a beautiful dress in the shop window.","ru":"В витрине выставлено красивое платье.","vi":"Có một chiếc váy đẹp trong cửa sổ cửa hàng.","fa":"یک لباس زیبا در ویترین مغازه وجود دارد."},{"de":"Wir haben lange vor dem Schaufenster gestanden.","en":"We stood in front of the shop window for a long time.","ru":"Мы долго стояли перед витриной.","vi":"Chúng tôi đứng trước cửa sổ cửa hàng rất lâu.","fa":"مدت زیادی جلوی ویترین ایستادیم."},{"de":"Das Schaufenster wird zu Weihnachten geschmückt.","en":"The shop window is decorated for Christmas.","ru":"Витрина украшена к Рождеству.","vi":"Cửa sổ cửa hàng được trang trí đón Giáng sinh.","fa":"ویترین مغازه برای کریسمس تزئین شده است."}]},{"word":"der Schauspieler","en":"actor","ru":"актёр","vi":"diễn viên","fa":"بازیگر","examples":[{"de":"Er ist ein bekannter Schauspieler aus Deutschland.","en":"He is a well-known actor from Germany.","ru":"Он известный актёр из Германии.","vi":"Anh là một diễn viên nổi tiếng đến từ Đức.","fa":"او بازیگر سرشناس آلمانی است."},{"de":"Der Schauspieler spielte seine Rolle sehr überzeugend.","en":"The actor played his role very convincingly.","ru":"Актёр очень убедительно сыграл свою роль.","vi":"Nam diễn viên đã nhập vai rất thuyết phục.","fa":"این بازیگر نقش خود را بسیار متقاعد کننده بازی کرد."}]},{"word":"die Schauspielerin","en":"actress","ru":"актриса","vi":"nữ diễn viên","fa":"بازیگر زن","examples":[{"de":"Die Schauspielerin bekam einen Preis für ihren Film.","en":"The actress won an award for her film.","ru":"Актриса получила награду за свой фильм.","vi":"Nữ diễn viên đã nhận được giải thưởng cho bộ phim của mình.","fa":"این بازیگر برای فیلمش جایزه دریافت کرد."},{"de":"Sie ist eine bekannte Schauspielerin aus Österreich.","en":"She is a well-known actress from Austria.","ru":"Она известная актриса из Австрии.","vi":"Cô là một nữ diễn viên nổi tiếng đến từ Áo.","fa":"او یک بازیگر سرشناس اهل اتریش است."},{"de":"Die junge Schauspielerin stand zum ersten Mal auf der Bühne.","en":"The young actress was on stage for the first time.","ru":"Молодая актриса впервые вышла на сцену.","vi":"Nữ diễn viên trẻ lần đầu tiên lên sân khấu.","fa":"این بازیگر جوان برای اولین بار روی صحنه رفت."}]},{"word":"die Scheibe","en":"slice; (window) pane","ru":"ломтик; стекло (оконное)","vi":"cái đĩa","fa":"دیسک","examples":[{"de":"Ich hätte gern noch eine Scheibe Brot.","en":"I would like another slice of bread.","ru":"Я бы хотел ещё один ломтик хлеба.","vi":"Tôi muốn một lát bánh mì nữa.","fa":"من یک تکه نان دیگر می خواهم."},{"de":"Die Scheibe des Fensters ist zerbrochen.","en":"The window pane is broken.","ru":"Оконное стекло разбито.","vi":"Ô cửa sổ bị vỡ.","fa":"شیشه پنجره شکسته است."}]},{"word":"scheiden","en":"to divorce; to separate","ru":"разводиться; разделять, отделять","vi":"ly hôn","fa":"طلاق","examples":[{"de":"Sie haben sich nach zehn Jahren scheiden lassen.","en":"They got divorced after ten years.","ru":"Они развелись через десять лет.","vi":"Họ ly hôn sau mười năm.","fa":"بعد از ده سال طلاق گرفتند."},{"de":"Das Paar will sich scheiden lassen.","en":"The couple want to get divorced.","ru":"Пара хочет развестись.","vi":"Hai vợ chồng muốn ly hôn.","fa":"این زوج می خواهند طلاق بگیرند."},{"de":"An dieser Frage scheiden sich die Meinungen.","en":"Opinions are divided on this question.","ru":"Мнения по этому вопросу расходятся.","vi":"Ý kiến ​​​​khác nhau về câu hỏi này.","fa":"نظرات در مورد این سوال متفاوت است."}]},{"word":"die Scheidung","en":"divorce","ru":"развод","vi":"vụ ly hôn","fa":"طلاق","examples":[{"de":"Die Scheidung wurde vor Gericht ausgesprochen.","en":"The divorce was granted in court.","ru":"Развод был оформлен в суде.","vi":"Việc ly hôn được công bố tại tòa án.","fa":"طلاق در دادگاه اعلام شد."},{"de":"Nach der Scheidung blieben sie trotzdem Freunde.","en":"After the divorce they still remained friends.","ru":"После развода они всё же остались друзьями.","vi":"Sau khi ly hôn, họ vẫn là bạn bè.","fa":"پس از طلاق، آنها همچنان دوست بودند."}]},{"word":"der Schein","en":"certificate; banknote; glow/light","ru":"справка; банкнота; свет/сияние","vi":"sự xuất hiện","fa":"ظاهر","examples":[{"de":"Er hat mir einen Fünfzig-Euro-Schein gegeben.","en":"He gave me a fifty-euro note.","ru":"Он дал мне купюру в пятьдесят евро.","vi":"Anh ấy đưa cho tôi tờ năm mươi euro.","fa":"یک اسکناس پنجاه یورویی به من داد."},{"de":"Im Schein der Kerze konnten wir kaum lesen.","en":"In the glow of the candle we could hardly read.","ru":"При свете свечи мы едва могли читать.","vi":"Chúng tôi hầu như không thể đọc được dưới ánh nến.","fa":"در نور شمع به سختی می توانستیم بخوانیم."}]},{"word":"scheinen","en":"to seem; to shine","ru":"казаться; светить","vi":"dường như","fa":"به نظر می رسد","examples":[{"de":"Die Sonne scheint heute den ganzen Tag.","en":"The sun is shining all day today.","ru":"Сегодня солнце светит весь день.","vi":"Hôm nay mặt trời chiếu sáng cả ngày.","fa":"امروز تمام روز خورشید می درخشد."},{"de":"Es scheint, dass er nicht kommen wird.","en":"It seems that he won't come.","ru":"Кажется, что он не придёт.","vi":"Có vẻ như anh ấy sẽ không đến.","fa":"انگار نمیاد"}]},{"word":"scheitern","en":"to fail","ru":"терпеть неудачу; проваливаться","vi":"thất bại","fa":"شکست بخورد","examples":[{"de":"Das Projekt ist am Geld gescheitert.","en":"The project failed because of money.","ru":"Проект провалился из-за денег.","vi":"Dự án thất bại vì tiền.","fa":"این پروژه به دلیل پول شکست خورد."},{"de":"Auch wenn du scheiterst, solltest du es weiter versuchen.","en":"Even if you fail, you should keep trying.","ru":"Даже если ты потерпишь неудачу, стоит продолжать пытаться.","vi":"Ngay cả khi bạn thất bại, bạn vẫn nên tiếp tục cố gắng.","fa":"حتی اگر شکست خوردید، باید به تلاش ادامه دهید."}]},{"word":"schenken","en":"to give (as a gift)","ru":"дарить","vi":"cho","fa":"دادن","examples":[{"de":"Zum Geburtstag schenke ich ihr ein Buch.","en":"For her birthday I'm giving her a book.","ru":"На день рождения я подарю ей книгу.","vi":"Tôi đang tặng cô ấy một cuốn sách vào ngày sinh nhật của cô ấy.","fa":"برای تولدش به او کتاب می دهم."},{"de":"Was schenkst du deinem Vater zu Weihnachten?","en":"What are you giving your father for Christmas?","ru":"Что ты подаришь отцу на Рождество?","vi":"Bạn sẽ tặng gì cho bố vào dịp Giáng sinh?","fa":"برای کریسمس چه چیزی برای پدرت می گیری؟"}]},{"word":"die Schere","en":"scissors","ru":"ножницы","vi":"cái kéo","fa":"قیچی","examples":[{"de":"Ich brauche eine Schere, um das Papier zu schneiden.","en":"I need scissors to cut the paper.","ru":"Мне нужны ножницы, чтобы разрезать бумагу.","vi":"Tôi cần kéo để cắt giấy.","fa":"برای بریدن کاغذ به قیچی نیاز دارم."},{"de":"Die Schere liegt in der Schublade.","en":"The scissors are in the drawer.","ru":"Ножницы лежат в ящике.","vi":"Chiếc kéo đang ở trong ngăn kéo.","fa":"قیچی در کشو است."}]},{"word":"der Schi","en":"ski (chiefly Austrian spelling of Ski)","ru":"лыжа (преимущественно австрийское написание слова Ski)","vi":"trượt tuyết","fa":"اسکی","examples":[{"de":"Im Winter fahren wir gern Schi.","en":"In winter we like to ski.","ru":"Зимой мы любим кататься на лыжах.","vi":"Chúng tôi thích trượt tuyết vào mùa đông.","fa":"ما دوست داریم در زمستان اسکی کنیم."},{"de":"Er hat sich neue Schi gekauft.","en":"He has bought new skis.","ru":"Он купил новые лыжи.","vi":"Anh ấy đã mua ván trượt mới.","fa":"اسکی نو خرید."},{"de":"In Österreich schreibt man oft Schi statt Ski.","en":"In Austria one often writes 'Schi' instead of 'Ski'.","ru":"В Австрии часто пишут «Schi» вместо «Ski».","vi":"Ở Áo người ta thường viết ski thay vì ski.","fa":"در اتریش مردم اغلب به جای اسکی، اسکی می نویسند."}]},{"word":"der Schichtdienst","en":"shift work","ru":"сменная работа, работа по сменам","vi":"ca làm việc","fa":"نوبت کاری","examples":[{"de":"Im Krankenhaus arbeitet man oft im Schichtdienst.","en":"In the hospital people often work in shifts.","ru":"В больнице часто работают по сменам.","vi":"Trong bệnh viện bạn thường làm việc theo ca.","fa":"در بیمارستان اغلب در شیفت کار می کنید."},{"de":"Der Schichtdienst ist für ihren Körper sehr anstrengend.","en":"Shift work is very exhausting for her body.","ru":"Сменная работа очень изматывает её организм.","vi":"Làm việc theo ca rất căng thẳng cho cơ thể của bạn.","fa":"نوبت کاری برای بدن شما بسیار استرس زا است."},{"de":"Wegen des Schichtdienstes sieht er seine Familie selten.","en":"Because of the shift work he rarely sees his family.","ru":"Из-за сменной работы он редко видит семью.","vi":"Vì làm việc theo ca nên anh hiếm khi được gặp gia đình.","fa":"به دلیل نوبت کاری اش، به ندرت خانواده اش را می بیند."}]},{"word":"schick","en":"chic, smart, stylish","ru":"шикарный, стильный, элегантный","vi":"sang trọng","fa":"شیک","examples":[{"de":"Du siehst heute richtig schick aus.","en":"You look really smart today.","ru":"Ты сегодня выглядишь очень стильно.","vi":"Hôm nay trông bạn thật sang trọng.","fa":"شما امروز واقعا شیک به نظر می رسید."},{"de":"Sie trägt ein schickes schwarzes Kleid.","en":"She is wearing a chic black dress.","ru":"На ней шикарное чёрное платье.","vi":"Cô ấy đang mặc một chiếc váy đen sang trọng.","fa":"او یک لباس مشکی شیک پوشیده است."},{"de":"Das Restaurant ist sehr schick und teuer.","en":"The restaurant is very stylish and expensive.","ru":"Ресторан очень стильный и дорогой.","vi":"Nhà hàng rất sang trọng và đắt tiền.","fa":"رستوران بسیار شیک و گران است."}]},{"word":"schicken","en":"to send","ru":"отправлять","vi":"gửi","fa":"ارسال کنید","examples":[{"de":"Ich schicke dir die Fotos per E-Mail.","en":"I'll send you the photos by email.","ru":"Я отправлю тебе фотографии по электронной почте.","vi":"Tôi sẽ gửi cho bạn những bức ảnh qua email.","fa":"عکس ها رو برات ایمیل میکنم"},{"de":"Er hat mir gestern eine Nachricht geschickt.","en":"He sent me a message yesterday.","ru":"Вчера он отправил мне сообщение.","vi":"Anh ấy đã gửi cho tôi một tin nhắn ngày hôm qua.","fa":"دیروز به من پیام داد."}]},{"word":"schieben","en":"to push","ru":"толкать","vi":"đẩy","fa":"فشار دهید","examples":[{"de":"Wir müssen das Auto schieben, der Motor springt nicht an.","en":"We have to push the car, the engine won't start.","ru":"Нам нужно толкать машину, двигатель не заводится.","vi":"Chúng ta phải đẩy xe, máy không nổ.","fa":"ما باید ماشین را فشار دهیم، موتور روشن نمی شود."},{"de":"Sie schiebt den Kinderwagen durch den Park.","en":"She is pushing the stroller through the park.","ru":"Она катит коляску по парку.","vi":"Cô đẩy xe đẩy qua công viên.","fa":"او کالسکه را در پارک هل می دهد."}]},{"word":"der Schiedsrichter","en":"referee; umpire","ru":"судья (спортивный), арбитр","vi":"trọng tài","fa":"داور","examples":[{"de":"Der Schiedsrichter zeigte dem Spieler die rote Karte.","en":"The referee showed the player the red card.","ru":"Судья показал игроку красную карточку.","vi":"Trọng tài đã rút thẻ đỏ cho cầu thủ này.","fa":"داور به این بازیکن کارت قرمز نشان داد."},{"de":"Ohne Schiedsrichter kann das Spiel nicht beginnen.","en":"The match can't start without a referee.","ru":"Без судьи матч не может начаться.","vi":"Trận đấu không thể bắt đầu nếu không có trọng tài.","fa":"بازی بدون داور شروع نمی شود."},{"de":"Die Fans waren mit dem Schiedsrichter unzufrieden.","en":"The fans were unhappy with the referee.","ru":"Болельщики были недовольны судьёй.","vi":"Người hâm mộ không hài lòng với trọng tài.","fa":"هواداران از داوری ناراضی بودند."}]},{"word":"schief","en":"crooked; tilted","ru":"кривой; косой","vi":"quanh co","fa":"کج","examples":[{"de":"Das Bild an der Wand hängt schief.","en":"The picture on the wall is hanging crooked.","ru":"Картина на стене висит криво.","vi":"Bức tranh trên tường bị cong.","fa":"عکس روی دیوار کج است."},{"de":"Der alte Zaun steht ganz schief.","en":"The old fence is standing quite crooked.","ru":"Старый забор стоит совсем криво.","vi":"Hàng rào cũ cong queo.","fa":"حصار قدیمی کج است."}]},{"word":"schießen","en":"to shoot","ru":"стрелять","vi":"bắn","fa":"شلیک کنید","examples":[{"de":"Der Jäger hat auf das Tier geschossen.","en":"The hunter shot at the animal.","ru":"Охотник выстрелил в животное.","vi":"Người thợ săn đã bắn con vật.","fa":"شکارچی به حیوان شلیک کرد."},{"de":"Der Spieler schoss das entscheidende Tor.","en":"The player scored the decisive goal.","ru":"Игрок забил решающий гол.","vi":"Cầu thủ này đã ghi bàn thắng quyết định.","fa":"این بازیکن گل تعیین کننده را به ثمر رساند."}]},{"word":"das Schiff","en":"ship","ru":"корабль","vi":"con tàu","fa":"کشتی","examples":[{"de":"Das Schiff fährt von Hamburg nach New York.","en":"The ship sails from Hamburg to New York.","ru":"Корабль плывёт из Гамбурга в Нью-Йорк.","vi":"Con tàu đi từ Hamburg đến New York.","fa":"این کشتی از هامبورگ به نیویورک سفر می کند."},{"de":"Wir machten eine Reise mit einem großen Schiff.","en":"We took a trip on a big ship.","ru":"Мы совершили путешествие на большом корабле.","vi":"Chúng tôi đã có một chuyến đi trên một con tàu lớn.","fa":"با یک کشتی بزرگ به سفر رفتیم."}]},{"word":"das Schild","en":"sign","ru":"табличка; знак","vi":"dấu hiệu","fa":"علامت","examples":[{"de":"An der Tür hängt ein Schild mit den Öffnungszeiten.","en":"There is a sign on the door with the opening hours.","ru":"На двери висит табличка с часами работы.","vi":"Trên cửa có tấm bảng ghi giờ mở cửa.","fa":"روی در تابلویی با ساعات کار وجود دارد."},{"de":"Beachte das Verkehrsschild an der Kreuzung.","en":"Pay attention to the traffic sign at the intersection.","ru":"Обрати внимание на дорожный знак на перекрёстке.","vi":"Hãy chú ý biển báo giao thông ở ngã tư.","fa":"به تابلوی راهنمایی و رانندگی در تقاطع توجه کنید."}]},{"word":"schildern","en":"to describe, to portray, to recount","ru":"описывать, излагать, рассказывать","vi":"mô tả","fa":"توصیف کنید","examples":[{"de":"Bitte schildern Sie den Unfall genau.","en":"Please describe the accident exactly.","ru":"Пожалуйста, точно опишите аварию.","vi":"Hãy mô tả chi tiết vụ tai nạn.","fa":"لطفا حادثه را با جزئیات توضیح دهید."},{"de":"Er schilderte uns seine Reise durch Asien.","en":"He recounted his journey through Asia to us.","ru":"Он рассказал нам о своём путешествии по Азии.","vi":"Anh ấy mô tả hành trình xuyên Châu Á của mình cho chúng tôi nghe.","fa":"او سفر خود را در آسیا برای ما تعریف کرد."},{"de":"Die Zeugin schilderte, was sie gesehen hatte.","en":"The witness described what she had seen.","ru":"Свидетельница описала то, что видела.","vi":"Nhân chứng mô tả những gì cô đã thấy.","fa":"شاهد چیزی که دیده بود تعریف کرد."}]},{"word":"schimpfen","en":"to scold; to grumble","ru":"ругать(ся); браниться","vi":"la mắng","fa":"سرزنش کردن","examples":[{"de":"Die Mutter schimpft mit dem Kind, weil es die Regel gebrochen hat.","en":"The mother scolds the child because it broke the rule.","ru":"Мать ругает ребёнка за то, что он нарушил правило.","vi":"Mẹ mắng con vì vi phạm nội quy.","fa":"مادر کودک را به خاطر قانون شکنی سرزنش می کند."},{"de":"Er schimpft immer über das schlechte Wetter.","en":"He always grumbles about the bad weather.","ru":"Он всегда ворчит из-за плохой погоды.","vi":"Anh ấy luôn phàn nàn về thời tiết xấu.","fa":"او همیشه از بدی آب و هوا شاکی است."}]},{"word":"der Schinken","en":"ham","ru":"ветчина","vi":"giăm bông","fa":"ژامبون","examples":[{"de":"Ich hätte gern ein Brötchen mit Schinken.","en":"I would like a roll with ham.","ru":"Я бы хотел булочку с ветчиной.","vi":"Tôi muốn một cuộn với giăm bông.","fa":"من یک رول با ژامبون می خواهم."},{"de":"Der Schinken wird in dünne Scheiben geschnitten.","en":"The ham is cut into thin slices.","ru":"Ветчину нарезают тонкими ломтиками.","vi":"Thịt giăm bông được cắt thành lát mỏng.","fa":"ژامبون به برش های نازک بریده می شود."}]},{"word":"die Schippe","en":"a shovel; also a shovelful of something","ru":"лопата; также совок, полная лопата чего-либо","vi":"cái xẻng","fa":"بیل","examples":[{"de":"Sieben Schneeschipper schippen sieben Schippen Schnee.","en":"Seven snow-shovellers shovel seven shovelfuls of snow.","ru":"Семь снегоуборщиков сгребают семь лопат снега.","vi":"Bảy xẻng tuyết xúc bảy xẻng tuyết.","fa":"هفت بیل برف بیل هفت بیل برف."},{"de":"Hol bitte die Schippe aus dem Keller, der Weg muss frei werden.","en":"Please fetch the shovel from the cellar, the path needs clearing.","ru":"Принеси, пожалуйста, лопату из подвала, дорожку нужно расчистить.","vi":"Hãy lấy xẻng ra khỏi hầm, đường đi phải được thông thoáng.","fa":"لطفا بیل را از سرداب بیرون بیاورید، مسیر باید پاک شود."},{"de":"Mit einer einzigen Schippe Sand füllte er das letzte Loch.","en":"With a single shovelful of sand he filled the last hole.","ru":"Одной лопатой песка он засыпал последнюю ямку.","vi":"Anh ta chỉ dùng một xẻng cát lấp đầy cái hố cuối cùng.","fa":"با یک بیل شن، آخرین سوراخ را پر کرد."}]},{"word":"der Schirm","en":"umbrella","ru":"зонт","vi":"chiếc ô","fa":"چتر","examples":[{"de":"Nimm deinen Schirm mit, es könnte regnen.","en":"Take your umbrella with you, it might rain.","ru":"Возьми зонт, может пойти дождь.","vi":"Hãy mang theo chiếc ô của bạn, trời có thể sẽ mưa.","fa":"چتر خود را با خود ببرید، ممکن است باران ببارد."},{"de":"Der Wind hat meinen Schirm kaputt gemacht.","en":"The wind broke my umbrella.","ru":"Ветер сломал мой зонт.","vi":"Gió làm gãy chiếc ô của tôi.","fa":"باد چترم را شکست."}]},{"word":"der Schlaf","en":"sleep","ru":"сон","vi":"giấc ngủ","fa":"خواب","examples":[{"de":"Nach dem langen Tag brauche ich viel Schlaf.","en":"After the long day I need a lot of sleep.","ru":"После долгого дня мне нужно много сна.","vi":"Sau một ngày dài tôi cần ngủ rất nhiều.","fa":"بعد از یک روز طولانی به خواب زیادی نیاز دارم."},{"de":"Guter Schlaf ist wichtig für die Gesundheit.","en":"Good sleep is important for your health.","ru":"Хороший сон важен для здоровья.","vi":"Giấc ngủ ngon rất quan trọng đối với sức khỏe.","fa":"خواب خوب برای سلامتی مهم است."},{"de":"Kaffee am Abend stört meinen Schlaf.","en":"Coffee in the evening disturbs my sleep.","ru":"Кофе вечером нарушает мой сон.","vi":"Cà phê vào buổi tối làm phiền giấc ngủ của tôi.","fa":"قهوه عصر خوابم را مختل می کند."}]},{"word":"die (Schlag-)Sahne/der (Schlag-)Rahm","en":"(whipped) cream","ru":"(взбитые) сливки","vi":"kem/kem (đánh bông)","fa":"خامه/خامه (هم زده).","examples":[{"de":"Auf den Kuchen kommt noch Schlagsahne.","en":"Whipped cream still goes on top of the cake.","ru":"На торт ещё добавляют взбитые сливки.","vi":"Ngoài ra còn có kem tươi trên bánh.","fa":"روی کیک خامه فرم گرفته هم هست."},{"de":"Möchtest du Rahm zu deinem Kaffee?","en":"Would you like cream with your coffee?","ru":"Хочешь сливки к своему кофе?","vi":"Bạn có muốn dùng kem với cà phê không?","fa":"آیا دوست دارید با قهوه خود خامه بخورید؟"}]},{"word":"schlagen","en":"to hit; to beat","ru":"бить; ударять","vi":"đánh","fa":"ضربه بزنید","examples":[{"de":"Man darf keine anderen Menschen schlagen.","en":"You must not hit other people.","ru":"Нельзя бить других людей.","vi":"Bạn không nên đánh người khác.","fa":"نباید دیگران را بزنی"},{"de":"Unsere Mannschaft hat das andere Team klar geschlagen.","en":"Our team clearly beat the other team.","ru":"Наша команда явно обыграла другую команду.","vi":"Đội của chúng tôi rõ ràng đã đánh bại đội kia.","fa":"تیم ما به وضوح تیم دیگر را شکست داد."}]},{"word":"das Schlagobers","en":"whipped cream (Austrian term)","ru":"взбитые сливки (австрийское слово)","vi":"kem tươi","fa":"خامه فرم گرفته","examples":[{"de":"Möchten Sie den Kaffee mit Schlagobers?","en":"Would you like the coffee with whipped cream?","ru":"Вам кофе со взбитыми сливками?","vi":"Bạn có muốn uống cà phê với kem không?","fa":"آیا قهوه با خامه فرم گرفته میل دارید؟"},{"de":"In Wien sagt man Schlagobers statt Schlagsahne.","en":"In Vienna people say 'Schlagobers' instead of 'Schlagsahne'.","ru":"В Вене говорят «Schlagobers» вместо «Schlagsahne».","vi":"Ở Vienna họ nói kem tươi thay vì kem tươi.","fa":"در وین به جای خامه فرم گرفته می گویند خامه فرم گرفته."},{"de":"Auf dem Kuchen ist viel Schlagobers.","en":"There is a lot of whipped cream on the cake.","ru":"На торте много взбитых сливок.","vi":"Có rất nhiều kem đánh bông trên bánh.","fa":"مقدار زیادی خامه فرم گرفته روی کیک وجود دارد."}]},{"word":"der Schlagrahm","en":"whipped cream (southern German/Austrian term)","ru":"взбитые сливки (южнонемецкое/австрийское слово)","vi":"kem tươi","fa":"خامه فرم گرفته","examples":[{"de":"Der Kuchen wird mit Schlagrahm serviert.","en":"The cake is served with whipped cream.","ru":"Торт подают со взбитыми сливками.","vi":"Bánh được ăn kèm với kem tươi.","fa":"کیک با خامه فرم گرفته سرو می شود."},{"de":"In Bayern hört man oft das Wort Schlagrahm.","en":"In Bavaria you often hear the word 'Schlagrahm'.","ru":"В Баварии часто можно услышать слово «Schlagrahm».","vi":"Ở Bavaria bạn thường nghe thấy từ kem đánh bông.","fa":"در باواریا اغلب کلمه خامه فرم گرفته را می شنوید."},{"de":"Ich nehme den Kakao mit Schlagrahm.","en":"I'll have the cocoa with whipped cream.","ru":"Мне какао со взбитыми сливками.","vi":"Tôi uống ca cao với kem tươi.","fa":"من کاکائو را با خامه فرم گرفته می گیرم."}]},{"word":"die Schlagsahne","en":"whipped cream","ru":"взбитые сливки","vi":"kem tươi","fa":"خامه فرم گرفته","examples":[{"de":"Den Kuchen esse ich am liebsten mit Schlagsahne.","en":"I like to eat the cake best with whipped cream.","ru":"Больше всего я люблю торт со взбитыми сливками.","vi":"Tôi thích ăn bánh với kem tươi hơn.","fa":"من ترجیح می دهم کیک را با خامه بخورم."},{"de":"Schlägst du bitte die Schlagsahne?","en":"Would you whip the cream, please?","ru":"Взобьёшь сливки, пожалуйста?","vi":"Bạn đánh bông kem được không?","fa":"لطفا خامه فرم گرفته را بزنید؟"},{"de":"Der heiße Kakao kommt mit Schlagsahne.","en":"The hot cocoa comes with whipped cream.","ru":"Горячее какао подаётся со взбитыми сливками.","vi":"Ca cao nóng đi kèm với kem tươi.","fa":"کاکائو داغ همراه با خامه فرم گرفته است."}]},{"word":"die Schlange","en":"snake; (also) queue","ru":"змея; очередь","vi":"con rắn","fa":"مار","examples":[{"de":"Im Zoo haben wir eine große Schlange gesehen.","en":"At the zoo we saw a big snake.","ru":"В зоопарке мы видели большую змею.","vi":"Chúng tôi nhìn thấy một con rắn lớn ở sở thú.","fa":"ما یک مار بزرگ را در باغ وحش دیدیم."},{"de":"Vor der Kasse stand eine lange Schlange.","en":"There was a long queue in front of the checkout.","ru":"У кассы стояла длинная очередь.","vi":"Có một hàng dài trước quầy thanh toán.","fa":"یک صف طولانی جلوی صندوق بود."}]},{"word":"schlank","en":"slim","ru":"стройный","vi":"mảnh khảnh","fa":"باریک","examples":[{"de":"Sie ist groß und schlank.","en":"She is tall and slim.","ru":"Она высокая и стройная.","vi":"Cô ấy cao và mảnh khảnh.","fa":"او قد بلند و لاغر است."},{"de":"Er treibt viel Sport, um schlank zu bleiben.","en":"He does a lot of sports to stay slim.","ru":"Он много занимается спортом, чтобы оставаться стройным.","vi":"Anh ấy chơi rất nhiều môn thể thao để giữ dáng.","fa":"او برای لاغر ماندن ورزش های زیادی انجام می دهد."}]},{"word":"schlecht","en":"bad","ru":"плохой","vi":"tệ","fa":"بد","examples":[{"de":"Das Essen im Restaurant hat schlecht geschmeckt.","en":"The food in the restaurant tasted bad.","ru":"Еда в ресторане была невкусной.","vi":"Đồ ăn trong nhà hàng có vị rất tệ.","fa":"غذای رستوران مزه بدی داشت."},{"de":"Mir geht es heute schlecht, ich bleibe zu Hause.","en":"I feel bad today, I'm staying home.","ru":"Сегодня я плохо себя чувствую, я останусь дома.","vi":"Hôm nay tôi cảm thấy tồi tệ, tôi đang ở nhà.","fa":"امروز حالم بد است، در خانه می مانم."}]},{"word":"schließen","en":"to close","ru":"закрывать","vi":"đóng","fa":"بستن","examples":[{"de":"Bitte schließen Sie die Tür, es zieht.","en":"Please close the door, there's a draft.","ru":"Пожалуйста, закройте дверь, дует.","vi":"Hãy đóng cửa lại, có gió lùa.","fa":"لطفا در را ببندید، پیش نویس وجود دارد."},{"de":"Das Geschäft schließt um achtzehn Uhr.","en":"The shop closes at six p.m.","ru":"Магазин закрывается в шесть часов вечера.","vi":"Cửa hàng đóng cửa lúc 6 giờ chiều.","fa":"ساعت 6 عصر مغازه بسته می شود."}]},{"word":"schließlich","en":"finally; after all","ru":"наконец; в конце концов","vi":"cuối cùng","fa":"در نهایت","examples":[{"de":"Nach langer Suche fanden wir schließlich einen Parkplatz.","en":"After a long search, we finally found a parking spot.","ru":"После долгих поисков мы наконец нашли парковочное место.","vi":"Sau một hồi tìm kiếm cuối cùng chúng tôi cũng tìm được chỗ đậu xe.","fa":"بعد از جستجوی طولانی بالاخره یک جای پارک پیدا کردیم."},{"de":"Du solltest ihm helfen, schließlich ist er dein Bruder.","en":"You should help him, after all, he's your brother.","ru":"Тебе следует помочь ему, ведь он твой брат.","vi":"Bạn nên giúp anh ấy, dù sao anh ấy cũng là anh trai của bạn.","fa":"شما باید به او کمک کنید، بالاخره او برادر شماست."}]},{"word":"schlimm","en":"bad; serious","ru":"плохой; серьёзный","vi":"tệ","fa":"بد","examples":[{"de":"Der Unfall war nicht so schlimm, wie wir dachten.","en":"The accident wasn't as bad as we thought.","ru":"Авария оказалась не такой серьёзной, как мы думали.","vi":"Tai nạn không tệ như chúng ta tưởng.","fa":"تصادف آنقدرها هم که فکر می کردیم بد نبود."},{"de":"Es ist schlimm, dass so viele Menschen keine Arbeit haben.","en":"It's bad that so many people don't have a job.","ru":"Плохо, что у стольких людей нет работы.","vi":"Thật tệ khi có quá nhiều người không có việc làm.","fa":"بد است که بسیاری از مردم شغل ندارند."}]},{"word":"das Schloss","en":"castle; lock","ru":"замок (крепость / устройство)","vi":"lâu đài","fa":"قلعه","examples":[{"de":"Wir haben am Wochenende ein altes Schloss besichtigt.","en":"We visited an old castle at the weekend.","ru":"На выходных мы осмотрели старый замок.","vi":"Chúng tôi đến thăm một lâu đài cổ vào cuối tuần.","fa":"آخر هفته از یک قلعه قدیمی بازدید کردیم."},{"de":"Das Schloss an der Tür ist kaputt.","en":"The lock on the door is broken.","ru":"Замок на двери сломан.","vi":"Ổ khóa trên cửa bị hỏng.","fa":"قفل در شکسته است."}]},{"word":"der Schluck","en":"sip, gulp, mouthful","ru":"глоток","vi":"ngụm","fa":"جرعه","examples":[{"de":"Darf ich einen Schluck von deinem Saft haben?","en":"May I have a sip of your juice?","ru":"Можно мне глоток твоего сока?","vi":"Tôi có thể uống một ngụm nước trái cây của bạn được không?","fa":"آیا می توانم یک جرعه از آب شما بخورم؟"},{"de":"Sie nahm einen großen Schluck Wasser.","en":"She took a big gulp of water.","ru":"Она сделала большой глоток воды.","vi":"Cô uống một ngụm nước dài.","fa":"او مدت زیادی آب خورد."},{"de":"Im Glas ist nur noch ein Schluck Wein.","en":"There's only a mouthful of wine left in the glass.","ru":"В стакане остался лишь глоток вина.","vi":"Trong ly chỉ còn lại một ngụm rượu.","fa":"فقط یک جرعه شراب در لیوان باقی مانده است."}]},{"word":"der Schluss","en":"end; conclusion","ru":"конец; заключение","vi":"kết luận","fa":"نتیجه گیری","examples":[{"de":"Am Schluss des Films weinten alle Zuschauer.","en":"At the end of the film, all the viewers cried.","ru":"В конце фильма все зрители плакали.","vi":"Cuối phim, tất cả khán giả đều khóc.","fa":"در پایان فیلم همه حاضران گریه می کردند."},{"de":"Zum Schluss möchte ich mich bei allen bedanken.","en":"In conclusion, I would like to thank everyone.","ru":"В заключение я хочу поблагодарить всех.","vi":"Cuối cùng tôi xin gửi lời cảm ơn tới tất cả mọi người.","fa":"در پایان از همه تشکر می کنم."}]},{"word":"der Schlüssel","en":"key","ru":"ключ","vi":"chìa khóa","fa":"کلید","examples":[{"de":"Ich habe meinen Schlüssel verloren und komme nicht in die Wohnung.","en":"I lost my key and can't get into the apartment.","ru":"Я потерял ключ и не могу попасть в квартиру.","vi":"Tôi bị mất chìa khóa và không thể vào căn hộ.","fa":"کلیدم را گم کردم و نمی توانم وارد آپارتمان شوم."},{"de":"Kannst du mir bitte den Schlüssel für das Büro geben?","en":"Can you please give me the key to the office?","ru":"Можешь дать мне ключ от офиса?","vi":"Bạn có thể vui lòng đưa cho tôi chìa khóa văn phòng được không?","fa":"میشه لطفا کلید دفتر را به من بدهید؟"}]},{"word":"der Schlusssatz","en":"closing sentence; concluding sentence","ru":"заключительная фраза; финальное предложение","vi":"câu cuối cùng","fa":"جمله پایانی","examples":[{"de":"Der Schlusssatz des Briefes war sehr höflich.","en":"The closing sentence of the letter was very polite.","ru":"Заключительная фраза письма была очень вежливой.","vi":"Câu cuối cùng của bức thư rất lịch sự.","fa":"جمله پایانی نامه بسیار مودبانه بود."},{"de":"Ein guter Schlusssatz fasst alles zusammen.","en":"A good concluding sentence sums everything up.","ru":"Хорошая заключительная фраза подводит всему итог.","vi":"Một câu kết thúc hay sẽ tóm tắt mọi thứ.","fa":"یک جمله پایانی خوب همه چیز را خلاصه می کند."},{"de":"Im Schlusssatz bedankte sie sich für die Hilfe.","en":"In the closing sentence she thanked them for their help.","ru":"В заключительной фразе она поблагодарила за помощь.","vi":"Trong câu cuối cùng, cô ấy cảm ơn chúng tôi đã giúp đỡ.","fa":"در جمله آخر از کمک ما تشکر کرد."}]},{"word":"schmal","en":"narrow","ru":"узкий","vi":"thu hẹp","fa":"باریک","examples":[{"de":"Die Straße in der Altstadt ist sehr schmal.","en":"The street in the old town is very narrow.","ru":"Улица в старом городе очень узкая.","vi":"Đường phố trong phố cổ rất hẹp.","fa":"خیابان در شهر قدیمی بسیار باریک است."},{"de":"Er trägt gern schmale Hosen.","en":"He likes to wear narrow trousers.","ru":"Он любит носить узкие брюки.","vi":"Anh ấy thích mặc quần mỏng.","fa":"او دوست دارد شلوار باریک بپوشد."}]},{"word":"schmecken","en":"to taste","ru":"быть на вкус; нравиться на вкус","vi":"hương vị","fa":"طعم","examples":[{"de":"Die Suppe schmeckt sehr lecker.","en":"The soup tastes very delicious.","ru":"Суп очень вкусный.","vi":"Súp có vị rất ngon.","fa":"طعم سوپ بسیار خوشمزه است."},{"de":"Schmeckt dir der Kuchen?","en":"Do you like the taste of the cake?","ru":"Тебе нравится вкус торта?","vi":"Bạn có thích bánh không?","fa":"کیک رو دوست داری؟"}]},{"word":"schmelzen","en":"to melt","ru":"таять; плавить(ся)","vi":"tan chảy","fa":"ذوب شود","examples":[{"de":"Das ewige Eis beginnt am Pol immer früher zu schmelzen.","en":"The perennial ice at the pole is starting to melt earlier and earlier.","ru":"Вечный лёд на полюсе начинает таять всё раньше.","vi":"Băng vĩnh cửu bắt đầu tan ngày càng sớm hơn ở cực.","fa":"یخ ابدی زودتر و زودتر در قطب شروع به ذوب شدن می کند."},{"de":"In der Sonne schmilzt das Eis in meinem Glas sehr schnell.","en":"In the sun the ice in my glass melts very quickly.","ru":"На солнце лёд в моём стакане тает очень быстро.","vi":"Đá trong ly của tôi tan rất nhanh dưới ánh mặt trời.","fa":"یخ لیوان من خیلی سریع زیر آفتاب آب می شود."},{"de":"Die Schokolade ist in der Tasche völlig geschmolzen.","en":"The chocolate has completely melted in the bag.","ru":"Шоколад полностью растаял в кармане.","vi":"Sô cô la tan chảy hoàn toàn trong túi.","fa":"شکلات در کیسه کاملا ذوب شد."}]},{"word":"der Schmelzpunkt","en":"melting point","ru":"температура плавления","vi":"điểm nóng chảy","fa":"نقطه ذوب","examples":[{"de":"Eis erreicht seinen Schmelzpunkt bei null Grad.","en":"Ice reaches its melting point at zero degrees.","ru":"Лёд достигает температуры плавления при нуле градусов.","vi":"Băng đạt đến điểm nóng chảy ở mức 0 độ.","fa":"یخ در صفر درجه به نقطه ذوب خود می رسد."},{"de":"Jedes Metall hat einen eigenen Schmelzpunkt.","en":"Each metal has its own melting point.","ru":"У каждого металла своя температура плавления.","vi":"Mỗi kim loại đều có điểm nóng chảy riêng.","fa":"هر فلزی نقطه ذوب خاص خود را دارد."},{"de":"Am Schmelzpunkt wird der feste Stoff flüssig.","en":"At the melting point the solid becomes liquid.","ru":"При температуре плавления твёрдое вещество становится жидким.","vi":"Tại điểm nóng chảy chất rắn trở thành chất lỏng.","fa":"در نقطه ذوب ماده جامد به مایع تبدیل می شود."}]},{"word":"der Schmerz","en":"pain","ru":"боль","vi":"nỗi đau","fa":"درد","examples":[{"de":"Sie hat starke Schmerzen im Rücken.","en":"She has severe pain in her back.","ru":"У неё сильные боли в спине.","vi":"Cô ấy bị đau nặng ở lưng.","fa":"او درد شدیدی در کمر دارد."},{"de":"Nimm eine Tablette gegen den Schmerz.","en":"Take a pill for the pain.","ru":"Прими таблетку от боли.","vi":"Uống một viên thuốc để giảm đau.","fa":"برای درد قرص بخور"}]},{"word":"das Schmerzmittel","en":"painkiller; analgesic","ru":"обезболивающее, болеутоляющее средство","vi":"thuốc giảm đau","fa":"مسکن","examples":[{"de":"Der Arzt verschrieb mir ein starkes Schmerzmittel.","en":"The doctor prescribed me a strong painkiller.","ru":"Врач прописал мне сильное обезболивающее.","vi":"Bác sĩ kê cho tôi một loại thuốc giảm đau mạnh.","fa":"دکتر برایم مسکن قوی تجویز کرد."},{"de":"Nimm ein Schmerzmittel, wenn der Kopf wehtut.","en":"Take a painkiller if your head aches.","ru":"Прими обезболивающее, если болит голова.","vi":"Uống thuốc giảm đau nếu đầu bạn đau.","fa":"اگر سرتان درد می کند یک مسکن مصرف کنید."},{"de":"Dieses Schmerzmittel bekommt man ohne Rezept.","en":"You can get this painkiller without a prescription.","ru":"Это обезболивающее можно купить без рецепта.","vi":"Bạn có thể mua thuốc giảm đau này mà không cần toa bác sĩ.","fa":"این مسکن را می توانید بدون نسخه تهیه کنید."}]},{"word":"schminken","en":"to put on makeup","ru":"краситься, наносить макияж","vi":"trang điểm","fa":"آرایش کردن","examples":[{"de":"Sie schminkt sich jeden Morgen vor der Arbeit.","en":"She puts on makeup every morning before work.","ru":"Она красится каждое утро перед работой.","vi":"Cô ấy trang điểm vào mỗi buổi sáng trước khi đi làm.","fa":"او هر روز صبح قبل از کار آرایش می کند."},{"de":"Für die Party hat sie sich besonders schön geschminkt.","en":"For the party, she did her makeup especially nicely.","ru":"Для вечеринки она сделала особенно красивый макияж.","vi":"Cô trang điểm đặc biệt xinh đẹp cho bữa tiệc.","fa":"او برای مهمانی آرایش زیبایی انجام داد."}]},{"word":"der Schmuck","en":"jewelry","ru":"украшения","vi":"đồ trang sức","fa":"جواهرات","examples":[{"de":"Meine Großmutter hat mir wertvollen Schmuck geschenkt.","en":"My grandmother gave me valuable jewelry.","ru":"Бабушка подарила мне ценные украшения.","vi":"Bà tôi đã cho tôi đồ trang sức có giá trị.","fa":"مادربزرگم جواهرات ارزشمندی به من داد."},{"de":"Sie trägt gern goldenen Schmuck.","en":"She likes to wear gold jewelry.","ru":"Она любит носить золотые украшения.","vi":"Cô ấy thích đeo đồ trang sức bằng vàng.","fa":"او دوست دارد جواهرات طلا بپوشد."}]},{"word":"der Schmutz","en":"dirt","ru":"грязь","vi":"bụi bẩn","fa":"خاک","examples":[{"de":"Nach der Arbeit im Garten war seine Kleidung voller Schmutz.","en":"After working in the garden, his clothes were full of dirt.","ru":"После работы в саду его одежда была вся в грязи.","vi":"Sau khi làm vườn xong, quần áo của ông đầy bụi bẩn.","fa":"بعد از کار در باغ لباس هایش پر از خاک بود."},{"de":"Bitte putz den Schmutz von deinen Schuhen ab.","en":"Please clean the dirt off your shoes.","ru":"Пожалуйста, очисти грязь с обуви.","vi":"Hãy làm sạch bụi bẩn trên giày của bạn.","fa":"لطفا کثیفی کفش هایتان را پاک کنید."}]},{"word":"der Schnee","en":"snow","ru":"снег","vi":"tuyết","fa":"برف","examples":[{"de":"Im Winter liegt hier oft viel Schnee.","en":"In winter, there is often a lot of snow here.","ru":"Зимой здесь часто лежит много снега.","vi":"Ở đây thường có rất nhiều tuyết vào mùa đông.","fa":"اغلب در زمستان اینجا برف زیادی می بارد."},{"de":"Die Kinder spielen gern im Schnee.","en":"The children like to play in the snow.","ru":"Дети любят играть в снегу.","vi":"Trẻ em thích chơi trong tuyết.","fa":"بچه ها دوست دارند در برف بازی کنند."}]},{"word":"die Schneeschaufel","en":"snow shovel","ru":"лопата для снега, снегоуборочная лопата","vi":"xẻng tuyết","fa":"بیل برفی","examples":[{"de":"Mit der Schneeschaufel räumt er den Gehweg frei.","en":"With the snow shovel he clears the pavement.","ru":"Снеговой лопатой он расчищает тротуар.","vi":"Anh ta dọn sạch vỉa hè bằng xẻng xúc tuyết.","fa":"پیاده رو را با بیل برف پاک می کند."},{"de":"Die Schneeschaufel steht im Keller.","en":"The snow shovel is in the cellar.","ru":"Лопата для снега стоит в подвале.","vi":"Xẻng tuyết ở dưới tầng hầm.","fa":"بیل برفی در زیرزمین است."},{"de":"Wir brauchen eine neue Schneeschaufel für den Winter.","en":"We need a new snow shovel for the winter.","ru":"На зиму нам нужна новая лопата для снега.","vi":"Chúng ta cần một chiếc xẻng xúc tuyết mới cho mùa đông.","fa":"برای زمستان به یک بیل برفی جدید نیاز داریم."}]},{"word":"der Schneeschipper","en":"a person who shovels snow, a snow-shoveller","ru":"снегоуборщик (человек, убирающий снег)","vi":"xẻng tuyết","fa":"the snow shovel","examples":[{"de":"Sieben Schneeschipper schippen sieben Schippen Schnee.","en":"Seven snow-shovellers shovel seven shovelfuls of snow.","ru":"Семь снегоуборщиков сгребают семь лопат снега.","vi":"Bảy xẻng tuyết xúc bảy xẻng tuyết.","fa":"هفت بیل برف بیل هفت بیل برف."},{"de":"Im Winter verdient sich der Student als Schneeschipper etwas dazu.","en":"In winter the student earns a bit extra as a snow-shoveller.","ru":"Зимой студент подрабатывает снегоуборщиком.","vi":"Vào mùa đông, sinh viên kiếm thêm tiền bằng nghề xúc tuyết.","fa":"در زمستان، دانش آموز به عنوان یک بیل برفی درآمد اضافی کسب می کند."},{"de":"Der Schneeschipper war schon vor Sonnenaufgang auf dem Gehweg.","en":"The snow-shoveller was on the pavement before sunrise.","ru":"Снегоуборщик был на тротуаре ещё до восхода солнца.","vi":"Máy xúc tuyết đã ở trên vỉa hè trước khi mặt trời mọc.","fa":"برف کوب قبل از طلوع آفتاب در پیاده رو بود."}]},{"word":"das Schneidebrett","en":"chopping board","ru":"разделочная доска","vi":"cái thớt","fa":"تخته برش","examples":[{"de":"Schneide das Gemüse auf dem Schneidebrett klein.","en":"Chop the vegetables on the chopping board.","ru":"Нарежь овощи на разделочной доске.","vi":"Cắt rau trên thớt.","fa":"سبزیجات را روی تخته برش خرد کنید."},{"de":"Für rohes Fleisch nehme ich ein separates Schneidebrett.","en":"For raw meat I use a separate chopping board.","ru":"Для сырого мяса я беру отдельную разделочную доску.","vi":"Tôi sử dụng thớt riêng cho thịt sống.","fa":"من از تخته برش جداگانه برای گوشت خام استفاده می کنم."},{"de":"Das hölzerne Schneidebrett darf nicht in die Spülmaschine.","en":"The wooden chopping board mustn't go in the dishwasher.","ru":"Деревянную разделочную доску нельзя мыть в посудомоечной машине.","vi":"Thớt gỗ không thể cho vào máy rửa bát.","fa":"تخته برش چوبی را نمی توان در ماشین ظرفشویی قرار داد."}]},{"word":"schneiden","en":"to cut","ru":"резать; стричь","vi":"cắt","fa":"برش دادن","examples":[{"de":"Ich habe mir beim Kochen in den Finger geschnitten.","en":"I cut my finger while cooking.","ru":"Я порезал палец, когда готовил.","vi":"Tôi bị đứt tay khi đang nấu ăn.","fa":"هنگام آشپزی انگشتم را بریدم."},{"de":"Schneide das Brot bitte in dünne Scheiben.","en":"Please cut the bread into thin slices.","ru":"Нарежь, пожалуйста, хлеб тонкими ломтиками.","vi":"Hãy cắt bánh mì thành từng lát mỏng.","fa":"لطفا نان را به ورقه های نازک برش دهید."},{"de":"Der Friseur hat mir die Haare viel zu kurz geschnitten.","en":"The hairdresser cut my hair far too short.","ru":"Парикмахер подстриг мне волосы слишком коротко.","vi":"Thợ làm tóc đã cắt tóc của tôi quá ngắn.","fa":"آرایشگر موهایم را خیلی کوتاه کرد."}]},{"word":"schneien","en":"to snow","ru":"идти (о снеге)","vi":"tuyết","fa":"برف","examples":[{"de":"Draußen schneit es schon seit dem Morgen.","en":"It has been snowing outside since morning.","ru":"На улице идёт снег с самого утра.","vi":"Ngoài trời tuyết đã rơi từ sáng.","fa":"از صبح بیرون برف می بارد."},{"de":"Im Dezember schneit es hier meistens.","en":"In December, it usually snows here.","ru":"В декабре здесь обычно идёт снег.","vi":"Ở đây thường có tuyết vào tháng 12.","fa":"معمولاً در ماه دسامبر اینجا برف می بارد."}]},{"word":"schnell","en":"fast; quickly","ru":"быстрый; быстро","vi":"nhanh chóng","fa":"به سرعت","examples":[{"de":"Er fährt immer sehr schnell mit dem Auto.","en":"He always drives the car very fast.","ru":"Он всегда очень быстро водит машину.","vi":"Anh ấy luôn lái xe rất nhanh.","fa":"او همیشه ماشینش را خیلی سریع می راند."},{"de":"Komm schnell, der Bus fährt gleich ab!","en":"Come quickly, the bus is about to leave!","ru":"Иди быстрее, автобус вот-вот уедет!","vi":"Hãy đến nhanh lên, xe buýt sắp rời đi rồi!","fa":"سریع بیا، اتوبوس به زودی می رود!"}]},{"word":"das Schnitzel","en":"schnitzel (breaded cutlet)","ru":"шницель","vi":"schnitzel","fa":"شنیسل","examples":[{"de":"Wir haben im Restaurant ein Wiener Schnitzel bestellt.","en":"We ordered a Wiener schnitzel at the restaurant.","ru":"Мы заказали в ресторане венский шницель.","vi":"Chúng tôi gọi món Wiener Schnitzel trong nhà hàng.","fa":"ما یک وینر شنیتسل در رستوران سفارش دادیم."},{"de":"Das Schnitzel wird meistens mit Pommes serviert.","en":"Schnitzel is usually served with fries.","ru":"Шницель обычно подают с картофелем фри.","vi":"Schnitzel thường được ăn kèm với khoai tây chiên.","fa":"شنیسل معمولا با سیب زمینی سرخ شده سرو می شود."}]},{"word":"der Schnupfen","en":"cold (runny nose)","ru":"насморк","vi":"cái lạnh","fa":"سرما","examples":[{"de":"Ich habe einen Schnupfen und kann kaum atmen.","en":"I have a cold and can hardly breathe.","ru":"У меня насморк, я едва могу дышать.","vi":"Tôi bị cảm lạnh và khó thở.","fa":"سرما خورده ام و به سختی نفس می کشم."},{"de":"Bei diesem Wetter bekommt man leicht einen Schnupfen.","en":"In this weather, you easily catch a cold.","ru":"В такую погоду легко подхватить насморк.","vi":"Thời tiết này rất dễ bị cảm lạnh.","fa":"سرماخوردگی در این هوا آسان است."}]},{"word":"die Schokolade","en":"chocolate","ru":"шоколад","vi":"sô cô la","fa":"شکلات","examples":[{"de":"Die Kinder essen sehr gern Schokolade.","en":"The children really like eating chocolate.","ru":"Дети очень любят есть шоколад.","vi":"Bọn trẻ thực sự thích ăn sôcôla.","fa":"بچه ها خیلی دوست دارند شکلات بخورند."},{"de":"Ich habe ihr eine Tafel Schokolade zum Geburtstag geschenkt.","en":"I gave her a bar of chocolate for her birthday.","ru":"Я подарил ей плитку шоколада на день рождения.","vi":"Tôi đã tặng cô ấy một thanh sô cô la vào ngày sinh nhật của cô ấy.","fa":"برای تولدش یک شکلات به او دادم."}]},{"word":"schon","en":"already","ru":"уже","vi":"rồi","fa":"در حال حاضر","examples":[{"de":"Ich habe die Hausaufgaben schon gemacht.","en":"I have already done my homework.","ru":"Я уже сделал домашнее задание.","vi":"Tôi đã làm xong bài tập về nhà rồi.","fa":"من قبلاً تکالیفم را انجام داده ام."},{"de":"Bist du schon fertig?","en":"Are you already finished?","ru":"Ты уже закончил?","vi":"Bạn đã sẵn sàng chưa?","fa":"هنوز آماده ای؟"}]},{"word":"schön","en":"beautiful; nice","ru":"красивый; хороший","vi":"đẹp","fa":"زیبا","examples":[{"de":"Das Wetter ist heute wirklich schön.","en":"The weather is really nice today.","ru":"Погода сегодня действительно прекрасная.","vi":"Thời tiết hôm nay thật sự rất đẹp.","fa":"امروز هوا واقعا خوبه"},{"de":"Sie hat ein sehr schönes Kleid gekauft.","en":"She bought a very beautiful dress.","ru":"Она купила очень красивое платье.","vi":"Cô ấy đã mua một chiếc váy rất đẹp.","fa":"او یک لباس بسیار زیبا خرید."}]},{"word":"schonen","en":"to spare, to conserve, to be gentle on","ru":"беречь, щадить, сберегать","vi":"bảo vệ","fa":"محافظت کنید","examples":[{"de":"Mit dem Zug zu fahren schont die Umwelt.","en":"Travelling by train is gentle on the environment.","ru":"Ездить на поезде — значит беречь окружающую среду.","vi":"Đi du lịch bằng tàu hỏa bảo vệ môi trường.","fa":"سفر با قطار از محیط زیست محافظت می کند."},{"de":"Wir sollten unsere Ressourcen schonen.","en":"We should conserve our resources.","ru":"Мы должны беречь наши ресурсы.","vi":"Chúng ta nên bảo tồn tài nguyên của mình.","fa":"ما باید منابع خود را حفظ کنیم."},{"de":"Wer Wasser spart, schont auch das Klima.","en":"Whoever saves water also spares the climate.","ru":"Тот, кто экономит воду, бережёт и климат.","vi":"Nếu bạn tiết kiệm nước, bạn cũng bảo vệ khí hậu.","fa":"اگر در مصرف آب صرفه جویی کنید، از آب و هوا نیز محافظت می کنید."}]},{"word":"der Schrank","en":"cupboard; wardrobe","ru":"шкаф","vi":"tủ quần áo","fa":"گنجه","examples":[{"de":"Ich hänge meine Kleider in den Schrank.","en":"I hang my clothes in the wardrobe.","ru":"Я вешаю свою одежду в шкаф.","vi":"Tôi treo quần áo của mình vào tủ.","fa":"لباس هایم را در کمد آویزان می کنم."},{"de":"Der Schrank in der Küche ist voller Geschirr.","en":"The cupboard in the kitchen is full of dishes.","ru":"Шкаф на кухне полон посуды.","vi":"Chiếc tủ trong bếp chứa đầy bát đĩa.","fa":"کمد آشپزخانه پر از ظرف است."}]},{"word":"der Schreck","en":"fright; shock","ru":"испуг, страх","vi":"sự kinh hoàng","fa":"وحشت","examples":[{"de":"Was für ein Schreck, als das Telefon klingelte!","en":"What a fright when the phone rang!","ru":"Какой испуг, когда зазвонил телефон!","vi":"Thật sốc khi điện thoại reo!","fa":"چه شوکه شد وقتی تلفن زنگ خورد!"},{"de":"Sie bekam einen großen Schreck.","en":"She got a real fright.","ru":"Она не на шутку испугалась.","vi":"Cô ấy có một nỗi sợ hãi lớn.","fa":"ترس بزرگی به او دست داد."},{"de":"Der Schreck sitzt mir noch in den Knochen.","en":"The fright is still in my bones.","ru":"Я всё ещё не могу прийти в себя от испуга.","vi":"Cú sốc vẫn còn trong xương của tôi.","fa":"شوک هنوز در استخوان من است."}]},{"word":"der Schreck(en)","en":"fright; shock","ru":"испуг, шок","vi":"(những) nỗi sợ hãi","fa":"ترس (ها)","examples":[{"de":"Der laute Knall hat mir einen großen Schrecken eingejagt.","en":"The loud bang gave me a big fright.","ru":"Громкий хлопок сильно меня напугал.","vi":"Tiếng nổ lớn làm tôi vô cùng sợ hãi.","fa":"صدای هق هق بلند باعث ترس شدید من شد."},{"de":"Sie erholte sich schnell von dem Schrecken.","en":"She quickly recovered from the shock.","ru":"Она быстро оправилась от испуга.","vi":"Cô nhanh chóng hồi phục sau cú sốc.","fa":"او به سرعت از شوک خارج شد."}]},{"word":"schreiben","en":"to write","ru":"писать","vi":"viết","fa":"نوشتن","examples":[{"de":"Ich schreibe meiner Freundin jeden Tag eine Nachricht.","en":"I write a message to my girlfriend every day.","ru":"Я каждый день пишу сообщение своей подруге.","vi":"Tôi nhắn tin cho bạn gái tôi mỗi ngày.","fa":"هر روز به دوست دخترم پیام می دهم."},{"de":"Er schreibt gerade an einem neuen Buch.","en":"He is currently writing a new book.","ru":"Он сейчас пишет новую книгу.","vi":"Hiện tại anh ấy đang viết một cuốn sách mới.","fa":"او در حال حاضر مشغول نوشتن کتاب جدیدی است."}]},{"word":"schreien","en":"to shout, scream","ru":"кричать","vi":"hét lên","fa":"فریاد زدن","examples":[{"de":"Das Baby hat die ganze Nacht geschrien.","en":"The baby screamed all night.","ru":"Ребёнок кричал всю ночь.","vi":"Bé khóc suốt đêm.","fa":"بچه تمام شب گریه کرد."},{"de":"Du musst nicht so schreien, ich höre dich gut.","en":"You don't need to shout like that, I can hear you well.","ru":"Не нужно так кричать, я хорошо тебя слышу.","vi":"Bạn không cần phải hét lên như vậy, tôi có thể nghe thấy bạn.","fa":"لازم نیست اینطور جیغ بزنی، من صدایت را خوب می شنوم."}]},{"word":"die Schrift","en":"writing; script","ru":"письмо, почерк, шрифт","vi":"văn bản","fa":"نوشته","examples":[{"de":"Seine Schrift ist so klein, dass ich sie kaum lesen kann.","en":"His handwriting is so small that I can hardly read it.","ru":"Его почерк такой мелкий, что я едва могу его прочитать.","vi":"Chữ viết của anh ấy quá nhỏ đến nỗi tôi khó có thể đọc được.","fa":"نوشته هایش آنقدر کوچک است که به سختی می توانم آن را بخوانم."},{"de":"Das Dokument ist in einer alten Schrift verfasst.","en":"The document is written in an old script.","ru":"Документ написан старинным шрифтом.","vi":"Tài liệu này được viết bằng chữ cổ.","fa":"این سند به خط باستانی نوشته شده است."}]},{"word":"der Schriftsteller","en":"writer; author","ru":"писатель","vi":"nhà văn","fa":"نویسنده","examples":[{"de":"Der Schriftsteller las aus seinem neuen Roman vor.","en":"The writer read from his new novel.","ru":"Писатель читал отрывки из своего нового романа.","vi":"Nhà văn đọc từ cuốn tiểu thuyết mới của mình.","fa":"نویسنده از رمان جدیدش خواند."},{"de":"Goethe war ein berühmter deutscher Schriftsteller.","en":"Goethe was a famous German writer.","ru":"Гёте был знаменитым немецким писателем.","vi":"Goethe là một nhà văn nổi tiếng người Đức.","fa":"گوته نویسنده مشهور آلمانی بود."},{"de":"Als Schriftsteller arbeitet er meistens allein.","en":"As a writer he mostly works alone.","ru":"Как писатель он работает в основном в одиночестве.","vi":"Là một nhà văn, anh chủ yếu làm việc một mình.","fa":"به عنوان نویسنده بیشتر به تنهایی کار می کند."}]},{"word":"die Schriftstellerin","en":"writer (female)","ru":"писательница","vi":"nhà văn","fa":"نویسنده","examples":[{"de":"Die bekannte Schriftstellerin hat einen neuen Roman veröffentlicht.","en":"The famous (female) writer has published a new novel.","ru":"Известная писательница выпустила новый роман.","vi":"Nhà văn nổi tiếng đã xuất bản một cuốn tiểu thuyết mới.","fa":"این نویسنده سرشناس رمان جدیدی منتشر کرده است."},{"de":"Meine Tante ist Schriftstellerin und schreibt vor allem Kinderbücher.","en":"My aunt is a writer and mainly writes children's books.","ru":"Моя тётя писательница и в основном пишет детские книги.","vi":"Dì tôi là nhà văn và chủ yếu viết sách cho trẻ em.","fa":"عمه من نویسنده است و بیشتر کتاب های کودک می نویسد."}]},{"word":"der Schritt","en":"step","ru":"шаг","vi":"bước","fa":"مرحله","examples":[{"de":"Er machte einen Schritt zurück, um besser zu sehen.","en":"He took a step back to see better.","ru":"Он сделал шаг назад, чтобы лучше видеть.","vi":"Anh lùi lại một bước để nhìn rõ hơn.","fa":"یک قدم به عقب رفت تا بهتر ببیند."},{"de":"Das ist ein wichtiger Schritt für unsere Firma.","en":"This is an important step for our company.","ru":"Это важный шаг для нашей фирмы.","vi":"Đây là một bước quan trọng đối với công ty chúng tôi.","fa":"این یک گام مهم برای شرکت ما است."}]},{"word":"die Schublade","en":"drawer","ru":"выдвижной ящик","vi":"ngăn kéo","fa":"کشو","examples":[{"de":"Die Gabeln sind in der zweiten Schublade.","en":"The forks are in the second drawer.","ru":"Вилки во втором ящике.","vi":"Những chiếc nĩa nằm trong ngăn kéo thứ hai.","fa":"چنگال ها در کشوی دوم هستند."},{"de":"Mach die Schublade vorsichtig zu, sie klemmt.","en":"Close the drawer carefully, it sticks.","ru":"Закрой ящик осторожно, он заедает.","vi":"Đóng ngăn kéo lại cẩn thận, nó bị kẹt.","fa":"کشو را با دقت ببندید، گیر کرده است."},{"de":"In dieser Schublade bewahren wir die Geschirrtücher auf.","en":"We keep the tea towels in this drawer.","ru":"В этом ящике мы храним кухонные полотенца.","vi":"Chúng tôi cất khăn trà trong ngăn kéo này.","fa":"حوله های چای را در این کشو نگهداری می کنیم."}]},{"word":"schüchtern","en":"shy, timid","ru":"застенчивый, робкий","vi":"nhút nhát","fa":"خجالتی","examples":[{"de":"Als Kind war er sehr schüchtern.","en":"As a child he was very shy.","ru":"В детстве он был очень застенчивым.","vi":"Lúc nhỏ anh rất nhút nhát.","fa":"در کودکی بسیار خجالتی بود."},{"de":"Sie lächelte schüchtern und sagte nichts.","en":"She smiled shyly and said nothing.","ru":"Она робко улыбнулась и ничего не сказала.","vi":"Cô cười ngượng ngùng không nói gì.","fa":"لبخند خجالتی زد و چیزی نگفت."},{"de":"Das schüchterne Mädchen traute sich nicht zu fragen.","en":"The shy girl did not dare to ask.","ru":"Застенчивая девочка не решилась спросить.","vi":"Cô gái nhút nhát không dám hỏi.","fa":"دختر خجالتی جرات نداشت بپرسد."}]},{"word":"der Schuh","en":"shoe","ru":"туфля, ботинок","vi":"chiếc giày","fa":"کفش","examples":[{"de":"Diese Schuhe sind sehr bequem zum Laufen.","en":"These shoes are very comfortable for walking.","ru":"Эти туфли очень удобны для ходьбы.","vi":"Những đôi giày này rất thoải mái khi chạy.","fa":"این کفش ها برای دویدن بسیار راحت هستند."},{"de":"Zieh bitte die Schuhe aus, bevor du reinkommst.","en":"Please take off your shoes before coming in.","ru":"Пожалуйста, сними обувь, прежде чем войти.","vi":"Vui lòng cởi giày trước khi vào.","fa":"لطفا قبل از ورود کفش های خود را در بیاورید."}]},{"word":"die Schularbeit","en":"test (written classroom exam, Austrian)","ru":"контрольная работа (в школе, австр.)","vi":"công việc ở trường","fa":"کار مدرسه","examples":[{"de":"Er hat morgen eine Schularbeit in Mathematik.","en":"He has a test in maths tomorrow.","ru":"Завтра у него контрольная по математике.","vi":"Ngày mai anh ấy có bài kiểm tra toán.","fa":"فردا امتحان ریاضی داره"},{"de":"Für die Schularbeit am Montag muss ich noch viel üben.","en":"I still need to practice a lot for the test on Monday.","ru":"Мне нужно ещё много позаниматься перед контрольной в понедельник.","vi":"Tôi vẫn phải luyện tập rất nhiều cho bài tập ở trường vào thứ Hai.","fa":"من هنوز باید برای کارهای مدرسه ام در روز دوشنبه خیلی تمرین کنم."}]},{"word":"die Schuld","en":"guilt; debt; fault","ru":"вина; долг","vi":"tội lỗi","fa":"گناه","examples":[{"de":"Er hat die Schuld auf sich genommen.","en":"He took the blame on himself.","ru":"Он взял вину на себя.","vi":"Anh ấy đã nhận lỗi.","fa":"او تقصیر را به عهده گرفت."},{"de":"Wir haben noch Schulden bei der Bank.","en":"We still have debts at the bank.","ru":"У нас ещё есть долги перед банком.","vi":"Chúng tôi vẫn còn nợ ngân hàng.","fa":"ما هنوز به بانک بدهکاریم."}]},{"word":"die Schulden","en":"debts (plural)","ru":"долги (мн. ч.)","vi":"các khoản nợ","fa":"بدهی ها","examples":[{"de":"Nach dem Studium hatte sie hohe Schulden bei der Bank.","en":"After her degree she had high debts with the bank.","ru":"После учёбы у неё были большие долги перед банком.","vi":"Sau khi tốt nghiệp, cô mắc nợ ngân hàng rất nhiều.","fa":"او پس از فارغ التحصیلی، بدهی های زیادی به بانک داشت."},{"de":"Er versucht seit Jahren, seine Schulden abzuzahlen.","en":"He has been trying to pay off his debts for years.","ru":"Он уже много лет пытается выплатить свои долги.","vi":"Anh ấy đã cố gắng trả hết nợ trong nhiều năm.","fa":"او سال‌هاست که تلاش می‌کند بدهی‌هایش را بپردازد."},{"de":"Ohne ein festes Einkommen wachsen die Schulden immer weiter.","en":"Without a steady income, the debts keep on growing.","ru":"Без постоянного дохода долги продолжают расти.","vi":"Không có thu nhập ổn định, các khoản nợ tiếp tục tăng lên.","fa":"بدون درآمد ثابت، بدهی ها همچنان به رشد خود ادامه می دهند."}]},{"word":"schuldig","en":"guilty","ru":"виновный; должен (денег)","vi":"có tội","fa":"گناهکار","examples":[{"de":"Das Gericht erklärte den Angeklagten für schuldig.","en":"The court found the defendant guilty.","ru":"Суд признал подсудимого виновным.","vi":"Tòa án tuyên bố bị cáo có tội.","fa":"دادگاه متهم را مجرم اعلام کرد."},{"de":"Ich fühle mich schuldig, weil ich dich vergessen habe.","en":"I feel guilty because I forgot you.","ru":"Я чувствую себя виноватым, потому что забыл о тебе.","vi":"Tôi cảm thấy có lỗi vì đã quên em.","fa":"من احساس گناه می کنم چون تو را فراموش کردم."},{"de":"Niemand wollte sich schuldig fühlen.","en":"No one wanted to feel guilty.","ru":"Никто не хотел чувствовать себя виноватым.","vi":"Không ai muốn cảm thấy tội lỗi.","fa":"هیچ کس نمی خواست احساس گناه کند."}]},{"word":"die Schule","en":"school","ru":"школа","vi":"trường học","fa":"مدرسه","examples":[{"de":"Meine Tochter geht seit September in die Schule.","en":"My daughter has been going to school since September.","ru":"Моя дочь ходит в школу с сентября.","vi":"Con gái tôi đã đi học từ tháng 9.","fa":"دخترم از شهریور به مدرسه می رود."},{"de":"Nach der Schule spielen die Kinder im Park.","en":"After school, the children play in the park.","ru":"После школы дети играют в парке.","vi":"Sau giờ học bọn trẻ chơi ở công viên.","fa":"بعد از مدرسه بچه ها در پارک بازی می کنند."}]},{"word":"die Schulter","en":"shoulder","ru":"плечо","vi":"vai","fa":"شانه","examples":[{"de":"Er trägt die Tasche immer über der linken Schulter.","en":"He always carries the bag over his left shoulder.","ru":"Он всегда носит сумку на левом плече.","vi":"Anh ấy luôn mang túi qua vai trái.","fa":"او همیشه کیف را روی شانه چپ خود حمل می کند."},{"de":"Meine Schulter tut seit dem Training weh.","en":"My shoulder has hurt since the training.","ru":"У меня болит плечо после тренировки.","vi":"Vai của tôi đã bị đau kể từ khi tập luyện.","fa":"شانه ام از زمان تمرین درد می کند."}]},{"word":"schummeln","en":"to cheat, to fib","ru":"жульничать, мухлевать, привирать","vi":"gian lận","fa":"تقلب","examples":[{"de":"In der Prüfung darf man nicht schummeln.","en":"You are not allowed to cheat in the exam.","ru":"На экзамене нельзя списывать.","vi":"Bạn không được phép gian lận trong kỳ thi.","fa":"شما مجاز به تقلب در امتحان نیستید."},{"de":"Er hat beim Kartenspiel geschummelt.","en":"He cheated at the card game.","ru":"Он смошенничал в карточной игре.","vi":"Anh ta gian lận khi chơi bài.","fa":"او به کارت ها تقلب کرد."},{"de":"Manche Schüler versuchen heimlich zu schummeln.","en":"Some pupils secretly try to cheat.","ru":"Некоторые ученики тайком пытаются списывать.","vi":"Một số sinh viên cố gắng gian lận một cách bí mật.","fa":"برخی از دانش آموزان سعی می کنند مخفیانه تقلب کنند."}]},{"word":"die Schüssel","en":"bowl","ru":"миска","vi":"cái bát","fa":"کاسه","examples":[{"de":"Sie mischt den Teig in einer großen Schüssel.","en":"She mixes the dough in a large bowl.","ru":"Она замешивает тесто в большой миске.","vi":"Cô trộn bột vào một cái tô lớn.","fa":"او خمیر را در یک کاسه بزرگ مخلوط می کند."},{"de":"Stell die Salatschüssel bitte auf den Tisch.","en":"Please put the salad bowl on the table.","ru":"Поставь, пожалуйста, миску с салатом на стол.","vi":"Vui lòng đặt bát salad lên bàn.","fa":"لطفا کاسه سالاد را روی میز بگذارید."}]},{"word":"schütteln","en":"to shake","ru":"трясти","vi":"lắc","fa":"تکان دادن","examples":[{"de":"Bitte schütteln Sie die Flasche vor dem Öffnen.","en":"Please shake the bottle before opening.","ru":"Пожалуйста, встряхните бутылку перед открытием.","vi":"Hãy lắc chai trước khi mở.","fa":"لطفا قبل از باز کردن بطری را تکان دهید."},{"de":"Er schüttelte mir zur Begrüßung die Hand.","en":"He shook my hand in greeting.","ru":"Он пожал мне руку в знак приветствия.","vi":"Anh bắt tay tôi chào hỏi.","fa":"به نشانه سلام دستم را فشرد."}]},{"word":"der Schutz","en":"protection","ru":"защита","vi":"sự bảo vệ","fa":"حفاظت","examples":[{"de":"Der Helm bietet guten Schutz beim Radfahren.","en":"The helmet offers good protection when cycling.","ru":"Шлем обеспечивает хорошую защиту при езде на велосипеде.","vi":"Mũ bảo hiểm mang lại sự bảo vệ tốt khi đạp xe.","fa":"کلاه ایمنی هنگام دوچرخه سواری محافظت خوبی ارائه می دهد."},{"de":"Wir suchten Schutz vor dem Regen.","en":"We looked for shelter from the rain.","ru":"Мы искали укрытие от дождя.","vi":"Chúng tôi tìm chỗ trú mưa.","fa":"ما به دنبال سرپناهی از باران بودیم."},{"de":"Der Schutz der Umwelt ist sehr wichtig.","en":"The protection of the environment is very important.","ru":"Защита окружающей среды очень важна.","vi":"Bảo vệ môi trường là rất quan trọng.","fa":"حفاظت از محیط زیست بسیار مهم است."}]},{"word":"schützen","en":"to protect","ru":"защищать","vi":"bảo vệ","fa":"محافظت کنید","examples":[{"de":"Eine Sonnencreme schützt die Haut vor Sonnenbrand.","en":"Sunscreen protects the skin from sunburn.","ru":"Солнцезащитный крем защищает кожу от солнечных ожогов.","vi":"Kem chống nắng bảo vệ da khỏi bị cháy nắng.","fa":"کرم ضد آفتاب از پوست در برابر آفتاب سوختگی محافظت می کند."},{"de":"Wir müssen die Umwelt besser schützen.","en":"We need to protect the environment better.","ru":"Мы должны лучше защищать окружающую среду.","vi":"Chúng ta phải bảo vệ môi trường tốt hơn.","fa":"ما باید از محیط زیست بهتر محافظت کنیم."}]},{"word":"schwach","en":"weak","ru":"слабый","vi":"yếu đuối","fa":"ضعیف","examples":[{"de":"Nach der Krankheit fühlte er sich noch sehr schwach.","en":"After the illness, he still felt very weak.","ru":"После болезни он ещё чувствовал себя очень слабым.","vi":"Sau cơn bệnh, ông vẫn cảm thấy rất yếu.","fa":"بعد از این بیماری همچنان احساس ضعف می کرد."},{"de":"Das Signal des Handys ist hier ziemlich schwach.","en":"The phone signal is quite weak here.","ru":"Сигнал телефона здесь довольно слабый.","vi":"Tín hiệu điện thoại di động ở đây khá yếu.","fa":"سیگنال تلفن همراه در اینجا بسیار ضعیف است."}]},{"word":"die Schwäche","en":"weakness","ru":"слабость","vi":"điểm yếu","fa":"ضعف","examples":[{"de":"Jeder Mensch hat seine Stärken und Schwächen.","en":"Everyone has their strengths and weaknesses.","ru":"У каждого есть свои сильные и слабые стороны.","vi":"Mỗi người đều có điểm mạnh và điểm yếu.","fa":"هر فردی نقاط قوت و ضعف خود را دارد."},{"de":"Schokolade ist meine größte Schwäche.","en":"Chocolate is my biggest weakness.","ru":"Шоколад — моя самая большая слабость.","vi":"Sô cô la là điểm yếu lớn nhất của tôi.","fa":"شکلات بزرگترین نقطه ضعف من است."},{"de":"Plötzlich fühlte er eine große Schwäche im Körper.","en":"He suddenly felt a great weakness in his body.","ru":"Он вдруг почувствовал во всём теле сильную слабость.","vi":"Đột nhiên anh cảm thấy cơ thể mình yếu đuối vô cùng.","fa":"ناگهان ضعف شدیدی در بدنش احساس کرد."}]},{"word":"das Schwammerl","en":"mushroom (Austrian)","ru":"гриб (австр.)","vi":"nấm","fa":"قارچ","examples":[{"de":"Im Herbst sammeln wir gern Schwammerl im Wald.","en":"In autumn, we like to pick mushrooms in the forest.","ru":"Осенью мы любим собирать грибы в лесу.","vi":"Vào mùa thu, chúng tôi thích hái nấm trong rừng.","fa":"در پاییز ما دوست داریم قارچ ها را در جنگل جمع آوری کنیم."},{"de":"Aus den Schwammerln hat sie eine leckere Suppe gekocht.","en":"She cooked a delicious soup from the mushrooms.","ru":"Из грибов она сварила вкусный суп.","vi":"Cô ấy đã nấu một món súp ngon từ nấm.","fa":"او یک سوپ خوشمزه از قارچ درست کرد."}]},{"word":"die Schwangerschaft","en":"pregnancy","ru":"беременность","vi":"mang thai","fa":"بارداری","examples":[{"de":"Während der Schwangerschaft geht sie regelmäßig zum Arzt.","en":"During her pregnancy, she regularly goes to the doctor.","ru":"Во время беременности она регулярно ходит к врачу.","vi":"Cô đến gặp bác sĩ thường xuyên trong thời gian mang thai.","fa":"او در دوران بارداری به طور منظم به پزشک مراجعه می کند."},{"de":"Die Schwangerschaft dauert normalerweise neun Monate.","en":"A pregnancy usually lasts nine months.","ru":"Беременность обычно длится девять месяцев.","vi":"Mang thai thường kéo dài chín tháng.","fa":"بارداری معمولا نه ماه طول می کشد."}]},{"word":"schweben","en":"to float, glide","ru":"парить, плыть (по воздуху)","vi":"phao","fa":"شناور","examples":[{"de":"Die Tänzerin schien über die Bühne zu schweben.","en":"The dancer seemed to float across the stage.","ru":"Казалось, что танцор парит над сценой.","vi":"Người vũ công như bay lơ lửng trên sân khấu.","fa":"به نظر می رسید رقصنده در سراسر صحنه شناور بود."},{"de":"Beim Walzer schwebt das Paar leicht über das Parkett.","en":"In the waltz the couple glides lightly over the floor.","ru":"В вальсе пара легко скользит по паркету.","vi":"Trong điệu valse, cặp đôi lướt nhẹ trên sàn nhảy.","fa":"در طول والس، این زوج به آرامی روی زمین رقص شناور می شوند."},{"de":"Ihre Bewegungen waren so leicht, dass sie zu schweben schien.","en":"Her movements were so light that she seemed to float.","ru":"Её движения были такими лёгкими, что она словно парила.","vi":"Chuyển động của cô ấy nhẹ nhàng đến nỗi cô ấy dường như đang lơ lửng.","fa":"حرکات او آنقدر سبک بود که به نظر می رسید شناور است."}]},{"word":"schweigen","en":"to be silent","ru":"молчать","vi":"im lặng","fa":"ساکت","examples":[{"de":"Er schwieg lange, bevor er antwortete.","en":"He was silent for a long time before answering.","ru":"Он долго молчал, прежде чем ответить.","vi":"Anh im lặng một lúc lâu trước khi trả lời.","fa":"قبل از جواب دادن مدتها سکوت کرد."},{"de":"Bitte schweig, ich muss mich konzentrieren.","en":"Please be quiet, I need to concentrate.","ru":"Пожалуйста, помолчи, мне нужно сосредоточиться.","vi":"Làm ơn im lặng đi, tôi cần tập trung.","fa":"لطفا ساکت باشید، من باید تمرکز کنم."}]},{"word":"Schwein haben","en":"to be lucky (colloquial)","ru":"повезти, подфартить (разг.)","vi":"để được may mắn","fa":"خوش شانس بودن","examples":[{"de":"Der Bus war noch da — da hast du Schwein gehabt!","en":"The bus was still there — you were lucky!","ru":"Автобус ещё стоял — тебе повезло!","vi":"Xe buýt vẫn ở đó - bạn bị hỏng rồi!","fa":"اتوبوس هنوز اونجا بود - تو خراب شدی!"}]},{"word":"die Schweißermaske","en":"welding mask; welder's helmet","ru":"сварочная маска, маска сварщика","vi":"mặt nạ thợ hàn","fa":"ماسک جوشکار","examples":[{"de":"Beim Schweißen trägt er immer eine Schweißermaske.","en":"When welding he always wears a welding mask.","ru":"При сварке он всегда надевает сварочную маску.","vi":"Anh luôn đeo mặt nạ hàn khi hàn.","fa":"او همیشه هنگام جوشکاری از ماسک جوشکاری استفاده می کند."},{"de":"Die Schweißermaske schützt die Augen vor dem hellen Licht.","en":"The welding mask protects the eyes from the bright light.","ru":"Сварочная маска защищает глаза от яркого света.","vi":"Mặt nạ hàn bảo vệ mắt khỏi ánh sáng chói.","fa":"ماسک جوش از چشم ها در برابر نور شدید محافظت می کند."},{"de":"Ohne Schweißermaske darfst du nicht arbeiten.","en":"You are not allowed to work without a welding mask.","ru":"Без сварочной маски работать нельзя.","vi":"Bạn không được phép làm việc mà không có mặt nạ hàn.","fa":"شما مجاز به کار بدون ماسک جوشکاری نیستید."}]},{"word":"das Schweißgerät","en":"welding machine; welder","ru":"сварочный аппарат","vi":"máy hàn","fa":"دستگاه جوش","examples":[{"de":"Das Schweißgerät steht in der Werkstatt.","en":"The welding machine is in the workshop.","ru":"Сварочный аппарат стоит в мастерской.","vi":"Máy hàn đang ở trong xưởng.","fa":"دستگاه جوش در کارگاه است."},{"de":"Mit diesem Schweißgerät kann man Stahl verbinden.","en":"With this welding machine you can join steel.","ru":"Этим сварочным аппаратом можно соединять сталь.","vi":"Máy hàn này có thể được sử dụng để nối thép.","fa":"از این دستگاه جوش می توان برای اتصال فولاد استفاده کرد."},{"de":"Er schaltete das Schweißgerät vorsichtig ein.","en":"He switched on the welding machine carefully.","ru":"Он осторожно включил сварочный аппарат.","vi":"Anh cẩn thận bật máy hàn.","fa":"با احتیاط جوشکار را روشن کرد."}]},{"word":"schwer","en":"heavy; difficult","ru":"тяжёлый; трудный","vi":"khó khăn","fa":"دشوار است","examples":[{"de":"Der Koffer ist zu schwer, ich kann ihn nicht tragen.","en":"The suitcase is too heavy, I can't carry it.","ru":"Чемодан слишком тяжёлый, я не могу его нести.","vi":"Vali nặng quá, tôi không xách nổi.","fa":"چمدان خیلی سنگین است، نمی توانم آن را حمل کنم."},{"de":"Die Prüfung war sehr schwer.","en":"The exam was very difficult.","ru":"Экзамен был очень трудным.","vi":"Bài kiểm tra rất khó khăn.","fa":"امتحان خیلی سخت بود."}]},{"word":"schwerfallen","en":"to be difficult (for someone), to find hard","ru":"даваться с трудом (кому-либо)","vi":"khó khăn","fa":"سخت باشد","examples":[{"de":"Mir fällt es schwer, früh aufzustehen.","en":"I find it hard to get up early.","ru":"Мне трудно рано вставать.","vi":"Tôi thấy khó dậy sớm.","fa":"برایم سخت است که زود بیدار شوم."},{"de":"Der Abschied ist ihr sehr schwergefallen.","en":"The farewell was very hard for her.","ru":"Прощание далось ей очень тяжело.","vi":"Rất khó để cô ấy nói lời chia tay.","fa":"خداحافظی برایش خیلی سخت بود."},{"de":"Mathematik fällt vielen Schülern schwer.","en":"Maths is difficult for many pupils.","ru":"Математика тяжело даётся многим ученикам.","vi":"Nhiều học sinh thấy môn toán khó.","fa":"بسیاری از دانش آموزان ریاضیات را دشوار می دانند."}]},{"word":"die Schwerkraftforschung","en":"gravity research","ru":"исследование гравитации","vi":"nghiên cứu trọng lực","fa":"gravity research","examples":[{"de":"Die Schwerkraftforschung hilft, das Universum besser zu verstehen.","en":"Gravity research helps us understand the universe better.","ru":"Исследование гравитации помогает лучше понять Вселенную.","vi":"Nghiên cứu về trọng lực giúp hiểu rõ hơn về vũ trụ.","fa":"تحقیقات گرانش به درک بهتر جهان کمک می کند."},{"de":"Auf der Raumstation ist Schwerkraftforschung ein wichtiges Thema.","en":"On the space station, gravity research is an important topic.","ru":"На космической станции исследование гравитации — важная тема.","vi":"Nghiên cứu trọng lực là một chủ đề quan trọng trên trạm vũ trụ.","fa":"تحقیقات گرانش موضوع مهمی در ایستگاه فضایی است."},{"de":"Die Schwerkraftforschung beschäftigt viele Physiker.","en":"Gravity research occupies many physicists.","ru":"Исследованием гравитации занимаются многие физики.","vi":"Nghiên cứu về lực hấp dẫn chiếm lĩnh nhiều nhà vật lý.","fa":"تحقیقات گرانش بسیاری از فیزیکدانان را به خود مشغول کرده است."}]},{"word":"die Schwester","en":"sister","ru":"сестра","vi":"chị gái","fa":"خواهر","examples":[{"de":"Meine Schwester wohnt in einer anderen Stadt.","en":"My sister lives in another city.","ru":"Моя сестра живёт в другом городе.","vi":"Em gái tôi sống ở một thành phố khác.","fa":"خواهر من در شهر دیگری زندگی می کند."},{"de":"Ich habe zwei Schwestern und einen Bruder.","en":"I have two sisters and one brother.","ru":"У меня две сестры и один брат.","vi":"Tôi có hai chị gái và một anh trai.","fa":"من دو خواهر و یک برادر دارم."}]},{"word":"Schwieger-","en":"in-law (prefix)","ru":"приставка «...по браку» (тесть, тёща и т.п.)","vi":"con rể","fa":"خویشاوند سببی-","examples":[{"de":"Meine Schwiegermutter kocht sehr gut.","en":"My mother-in-law cooks very well.","ru":"Моя тёща (свекровь) очень хорошо готовит.","vi":"Mẹ chồng tôi nấu ăn rất ngon.","fa":"مادرشوهرم خیلی خوب آشپزی می کند."},{"de":"Am Sonntag besuchen wir meinen Schwiegervater.","en":"On Sunday we are visiting my father-in-law.","ru":"В воскресенье мы навещаем моего тестя (свёкра).","vi":"Vào Chủ Nhật, chúng tôi đến thăm bố vợ tôi.","fa":"یکشنبه به دیدن پدرشوهرم می رویم."}]},{"word":"schwierig","en":"difficult","ru":"трудный, сложный","vi":"khó khăn","fa":"دشوار است","examples":[{"de":"Diese Aufgabe ist für mich zu schwierig.","en":"This task is too difficult for me.","ru":"Это задание для меня слишком сложное.","vi":"Nhiệm vụ này quá khó đối với tôi.","fa":"این کار برای من خیلی سخت است."},{"de":"Es war eine schwierige Entscheidung, aber ich bereue sie nicht.","en":"It was a difficult decision, but I don't regret it.","ru":"Это было трудное решение, но я о нём не жалею.","vi":"Đó là một quyết định khó khăn nhưng tôi không hối hận.","fa":"تصمیم سختی بود، اما پشیمان نیستم."}]},{"word":"die Schwierigkeit","en":"difficulty","ru":"трудность, сложность","vi":"khó khăn","fa":"سختی","examples":[{"de":"Wir hatten große Schwierigkeiten, die Wohnung zu finden.","en":"We had great difficulty finding the flat.","ru":"Мы с большим трудом нашли квартиру.","vi":"Chúng tôi gặp khó khăn lớn trong việc tìm căn hộ.","fa":"ما برای پیدا کردن آپارتمان مشکل زیادی داشتیم."},{"de":"Bei der Prüfung gab es einige Schwierigkeiten.","en":"There were some difficulties in the exam.","ru":"На экзамене возникли некоторые трудности.","vi":"Có một số khó khăn trong quá trình thi.","fa":"در طول امتحان مشکلاتی وجود داشت."},{"de":"Sie löste das Problem ohne Schwierigkeit.","en":"She solved the problem without difficulty.","ru":"Она решила задачу без труда.","vi":"Cô ấy đã giải quyết được vấn đề mà không gặp khó khăn gì.","fa":"او مشکل را بدون مشکل حل کرد."}]},{"word":"schwimmen","en":"to swim","ru":"плавать","vi":"bơi lội","fa":"شنا کردن","examples":[{"de":"Im Sommer gehen wir oft im See schwimmen.","en":"In summer, we often go swimming in the lake.","ru":"Летом мы часто ходим плавать на озеро.","vi":"Vào mùa hè chúng tôi thường đi bơi ở hồ.","fa":"در تابستان ما اغلب برای شنا در دریاچه می رویم."},{"de":"Meine Tochter kann noch nicht schwimmen.","en":"My daughter can't swim yet.","ru":"Моя дочь ещё не умеет плавать.","vi":"Con gái tôi vẫn chưa biết bơi.","fa":"دخترم هنوز شنا بلد نیست."}]},{"word":"schwingen","en":"to oscillate, to swing","ru":"колебаться, качаться","vi":"đánh đu","fa":"تاب","examples":[{"de":"Das Pendel schwingt gleichmäßig hin und her.","en":"The pendulum swings back and forth evenly.","ru":"Маятник равномерно качается туда-сюда.","vi":"Con lắc dao động qua lại đều nhau.","fa":"آونگ به طور مساوی به جلو و عقب می چرخد."},{"de":"Eine Saite schwingt und erzeugt dabei einen Ton.","en":"A string oscillates and thereby produces a tone.","ru":"Струна колеблется и тем самым создаёт звук.","vi":"Một sợi dây dao động và phát ra âm thanh.","fa":"یک سیم می لرزد و صدا تولید می کند."},{"de":"Je länger das Pendel ist, desto langsamer schwingt es.","en":"The longer the pendulum is, the more slowly it swings.","ru":"Чем длиннее маятник, тем медленнее он качается.","vi":"Con lắc càng dài thì dao động càng chậm.","fa":"هرچه پاندول بلندتر باشد کندتر می چرخد."}]},{"word":"schwitzen","en":"to sweat","ru":"потеть","vi":"mồ hôi","fa":"عرق","examples":[{"de":"Bei dieser Hitze schwitze ich sehr stark.","en":"In this heat, I sweat a lot.","ru":"В такую жару я сильно потею.","vi":"Tôi đổ mồ hôi rất nhiều trong cái nóng này.","fa":"تو این گرما خیلی عرق می کنم."},{"de":"Nach dem Sport schwitzt er immer.","en":"He always sweats after sports.","ru":"После спорта он всегда потеет.","vi":"Anh ấy luôn đổ mồ hôi sau khi tập thể dục.","fa":"او همیشه بعد از ورزش عرق می کند."}]},{"word":"der Schwung","en":"swing, momentum","ru":"размах, кураж, инерция движения","vi":"động lực","fa":"حرکت","examples":[{"de":"Mit viel Schwung gleitet das Paar über die Tanzfläche.","en":"With a lot of swing the couple glides across the dance floor.","ru":"С большим размахом пара скользит по танцполу.","vi":"Cặp đôi lướt trên sàn nhảy với đà cực lớn.","fa":"این زوج با شتاب زیادی روی زمین رقص می چرخند."},{"de":"Der Tanz braucht Schwung und Leichtigkeit.","en":"The dance needs swing and lightness.","ru":"Танцу нужен размах и лёгкость.","vi":"Khiêu vũ cần có động lượng và sự nhẹ nhàng.","fa":"رقص نیاز به حرکت و سبکی دارد."},{"de":"Sie tanzte mit so viel Schwung, dass alle zusahen.","en":"She danced with so much swing that everyone watched.","ru":"Она танцевала с таким куражом, что все смотрели.","vi":"Cô ấy nhảy rất mạnh mẽ đến nỗi mọi người đều theo dõi.","fa":"آنقدر با قدرت رقصید که همه تماشا کردند."}]},{"word":"der See","en":"lake","ru":"озеро","vi":"hồ","fa":"دریاچه","examples":[{"de":"Wir machen am Wochenende einen Ausflug an den See.","en":"We are taking a trip to the lake this weekend.","ru":"На выходных мы едем на озеро.","vi":"Chúng tôi đang có một chuyến đi đến hồ vào cuối tuần này.","fa":"آخر این هفته به دریاچه سفر می کنیم."},{"de":"Der See ist im Sommer sehr warm.","en":"The lake is very warm in summer.","ru":"Летом озеро очень тёплое.","vi":"Hồ rất ấm áp vào mùa hè.","fa":"این دریاچه در تابستان بسیار گرم است."}]},{"word":"Das sehe ich anders","en":"I see it differently (polite disagreement)","ru":"Я вижу это иначе (вежливое несогласие)","vi":"Tôi thấy nó khác","fa":"من آن را متفاوت می بینم","examples":[{"de":"Das sehe ich anders, ich würde lieber fliegen.","en":"I see it differently, I'd rather fly.","ru":"Я вижу это иначе, я бы лучше полетел самолётом.","vi":"Tôi thấy nó khác, tôi thà bay.","fa":"من آن را متفاوت می بینم، ترجیح می دهم پرواز کنم."}]},{"word":"Das sehe ich auch so","en":"I see it that way too (agreement)","ru":"Я тоже так считаю (согласие)","vi":"Tôi cũng thấy vậy","fa":"منم همینطور میبینم","examples":[{"de":"Das sehe ich auch so, das ist zu teuer.","en":"I see it that way too, it's too expensive.","ru":"Я тоже так считаю, это слишком дорого.","vi":"Mình cũng thấy thế, đắt quá.","fa":"منم همینطور میبینمش خیلی گرونه"}]},{"word":"sehen","en":"to see","ru":"видеть","vi":"xem","fa":"ببینید","examples":[{"de":"Kannst du das Schild von hier aus sehen?","en":"Can you see the sign from here?","ru":"Ты видишь отсюда эту табличку?","vi":"Bạn có thể nhìn thấy biển báo từ đây không?","fa":"آیا می توانید علامت را از اینجا ببینید؟"},{"de":"Ich habe ihn gestern im Supermarkt gesehen.","en":"I saw him yesterday at the supermarket.","ru":"Я видел его вчера в супермаркете.","vi":"Hôm qua tôi nhìn thấy anh ấy ở siêu thị.","fa":"دیروز او را در سوپرمارکت دیدم."}]},{"word":"sehenswert","en":"worth seeing","ru":"достойный внимания, стоящий того, чтобы увидеть","vi":"đáng xem","fa":"ارزش دیدن داره","examples":[{"de":"Die alte Brücke ist wirklich sehenswert.","en":"The old bridge is really worth seeing.","ru":"Старый мост действительно стоит того, чтобы его увидеть.","vi":"Cây cầu cũ thực sự đáng xem.","fa":"پل قدیمی واقعا ارزش دیدن را دارد."},{"de":"In dieser Region gibt es viele sehenswerte Dörfer.","en":"There are many villages worth seeing in this region.","ru":"В этом регионе много деревень, достойных внимания.","vi":"Có rất nhiều ngôi làng đáng xem trong khu vực này.","fa":"روستاهای زیادی در این منطقه وجود دارد که ارزش دیدن دارند."},{"de":"Das Museum ist klein, aber durchaus sehenswert.","en":"The museum is small but well worth seeing.","ru":"Музей маленький, но вполне достойный внимания.","vi":"Bảo tàng nhỏ nhưng chắc chắn đáng xem.","fa":"موزه کوچک است، اما قطعا ارزش دیدن دارد."}]},{"word":"die Sehenswürdigkeit","en":"sight; tourist attraction","ru":"достопримечательность","vi":"điểm tham quan; thắng cảnh","fa":"جاذبه دیدنی","examples":[{"de":"Der Stephansdom ist die bekannteste Sehenswürdigkeit von Wien.","en":"St. Stephen's Cathedral is the most famous sight in Vienna.","ru":"Собор Святого Стефана — самая известная достопримечательность Вены.","vi":"Nhà thờ St. Stephen là điểm thu hút nổi tiếng nhất ở Vienna.","fa":"کلیسای جامع سنت استفان معروف ترین جاذبه در وین است."},{"de":"Wir haben in Paris viele Sehenswürdigkeiten besucht.","en":"We visited many tourist attractions in Paris.","ru":"В Париже мы посетили много достопримечательностей.","vi":"Chúng tôi đã đến thăm nhiều thắng cảnh ở Paris.","fa":"از دیدنی های پاریس دیدن کردیم."}]},{"word":"die Sehenswürdigkeit besichtigen","en":"to visit a sight, to do sightseeing","ru":"осматривать достопримечательность, посещать (о туризме)","vi":"tham quan ngắm cảnh","fa":"بازدید از منظره","examples":[{"de":"In Rom haben wir viele Sehenswürdigkeiten besichtigt.","en":"In Rome we visited many sights.","ru":"В Риме мы осмотрели много достопримечательностей.","vi":"Chúng tôi đã đến thăm nhiều thắng cảnh ở Rome.","fa":"ما از دیدنی های زیادی در رم بازدید کردیم."},{"de":"Welche Sehenswürdigkeit möchtest du zuerst besichtigen?","en":"Which sight do you want to visit first?","ru":"Какую достопримечательность ты хочешь осмотреть первой?","vi":"Bạn muốn ghé thăm cảnh tượng nào đầu tiên?","fa":"دوست دارید ابتدا از کدام منظره دیدن کنید؟"},{"de":"Wir besichtigten die alte Kirche im Zentrum.","en":"We visited the old church in the centre.","ru":"Мы осмотрели старую церковь в центре.","vi":"Chúng tôi đến thăm nhà thờ cũ ở trung tâm.","fa":"از کلیسای قدیمی در مرکز بازدید کردیم."}]},{"word":"die Sehnsucht","en":"longing; yearning","ru":"тоска; страстное желание","vi":"sự khao khát","fa":"اشتیاق","examples":[{"de":"Er hatte große Sehnsucht nach seiner Heimat.","en":"He had a great longing for his homeland.","ru":"Он сильно тосковал по родине.","vi":"Anh có một niềm khao khát mãnh liệt đối với quê hương.","fa":"اشتیاق زیادی به وطن داشت."},{"de":"Die Sehnsucht nach dem Meer wurde immer stärker.","en":"The longing for the sea grew ever stronger.","ru":"Тоска по морю становилась всё сильнее.","vi":"Niềm khao khát biển ngày càng mãnh liệt.","fa":"حسرت دریا بیشتر و قوی تر می شد."}]},{"word":"sehr","en":"very","ru":"очень","vi":"rất","fa":"خیلی","examples":[{"de":"Das Buch ist sehr interessant.","en":"The book is very interesting.","ru":"Книга очень интересная.","vi":"Cuốn sách rất thú vị.","fa":"کتاب بسیار جالبی است."},{"de":"Ich danke dir sehr für deine Hilfe.","en":"I thank you very much for your help.","ru":"Я очень благодарен тебе за помощь.","vi":"Cảm ơn bạn rất nhiều vì sự giúp đỡ của bạn.","fa":"از کمک شما بسیار سپاسگزارم."}]},{"word":"die Seife","en":"soap","ru":"мыло","vi":"xà phòng","fa":"صابون","examples":[{"de":"Bitte wasch dir die Hände mit Seife.","en":"Please wash your hands with soap.","ru":"Пожалуйста, помой руки с мылом.","vi":"Hãy rửa tay bằng xà phòng.","fa":"لطفا دست های خود را با صابون بشویید."},{"de":"Im Bad steht eine neue Seife.","en":"There is a new bar of soap in the bathroom.","ru":"В ванной лежит новое мыло.","vi":"Có xà phòng mới trong phòng tắm.","fa":"صابون جدید در حمام وجود دارد."}]},{"word":"sein","en":"to be","ru":"быть","vi":"được","fa":"باشد","examples":[{"de":"Er ist mein bester Freund.","en":"He is my best friend.","ru":"Он мой лучший друг.","vi":"Anh ấy là người bạn tốt nhất của tôi.","fa":"او بهترین دوست من است."},{"de":"Wir sind seit zwei Jahren verheiratet.","en":"We have been married for two years.","ru":"Мы женаты уже два года.","vi":"Chúng tôi đã kết hôn được hai năm.","fa":"ما دو سال است که ازدواج کرده ایم."}]},{"word":"seit","en":"since; for (time)","ru":"с (какого-то времени); в течение","vi":"kể từ khi","fa":"از آنجایی که","examples":[{"de":"Ich lerne seit drei Jahren Deutsch.","en":"I have been learning German for three years.","ru":"Я учу немецкий уже три года.","vi":"Tôi đã học tiếng Đức được ba năm.","fa":"من سه سال است که آلمانی یاد می گیرم."},{"de":"Seit dem Umzug fühlt sie sich viel wohler.","en":"Since the move, she feels much better.","ru":"С момента переезда она чувствует себя намного лучше.","vi":"Cô ấy đã cảm thấy tốt hơn nhiều kể từ khi chuyển đi.","fa":"او از زمان جابجایی احساس بسیار بهتری داشته است."}]},{"word":"seitdem","en":"since (then), ever since","ru":"с тех пор (как)","vi":"kể từ đó","fa":"از آن زمان","examples":[{"de":"Seitdem er umgezogen ist, sehen wir uns selten.","en":"Since he moved away, we rarely see each other.","ru":"С тех пор как он уехал, мы редко видимся.","vi":"Từ khi anh chuyển đi, chúng tôi hiếm khi gặp nhau.","fa":"از زمانی که او نقل مکان کرد، ما به ندرت یکدیگر را می بینیم."},{"de":"Sie hat vor einem Jahr angefangen und seitdem viel gelernt.","en":"She started a year ago and has learnt a lot since then.","ru":"Она начала год назад и с тех пор многому научилась.","vi":"Cô ấy bắt đầu làm việc cách đây một năm và đã học được rất nhiều điều kể từ đó.","fa":"او یک سال پیش شروع کرد و از آن زمان تاکنون چیزهای زیادی یاد گرفته است."},{"de":"Seitdem ich Sport mache, fühle ich mich besser.","en":"Ever since I started doing sport, I feel better.","ru":"С тех пор как я занялся спортом, я чувствую себя лучше.","vi":"Kể từ khi tôi bắt đầu tập thể dục, tôi cảm thấy tốt hơn.","fa":"از زمانی که ورزش را شروع کردم، احساس بهتری دارم."}]},{"word":"die Seite","en":"page; side","ru":"страница; сторона","vi":"trang","fa":"صفحه","examples":[{"de":"Bitte schlagen Sie das Buch auf Seite zwanzig auf.","en":"Please open the book to page twenty.","ru":"Пожалуйста, откройте книгу на двадцатой странице.","vi":"Hãy mở cuốn sách đến trang hai mươi.","fa":"لطفاً کتاب را تا صفحه بیستم باز کنید."},{"de":"Auf der anderen Seite der Straße ist ein Supermarkt.","en":"On the other side of the street, there is a supermarket.","ru":"На другой стороне улицы есть супермаркет.","vi":"Có một siêu thị ở phía bên kia đường.","fa":"در سمت دیگر خیابان یک سوپرمارکت وجود دارد."}]},{"word":"der Seiteneinsteiger","en":"career changer (lateral entrant)","ru":"человек, сменивший профессию; специалист без профильного образования","vi":"người tham gia bên","fa":"شرکت کننده جانبی","examples":[{"de":"Als Seiteneinsteiger kam er aus der Wirtschaft an die Schule.","en":"As a career changer, he came to the school from the business world.","ru":"Сменив профессию, он пришёл в школу из бизнеса.","vi":"Anh ấy đến trường với xuất thân kinh doanh.","fa":"او از یک پیشینه تجاری به مدرسه آمد."},{"de":"Viele Seiteneinsteiger bringen wertvolle Erfahrung mit.","en":"Many lateral entrants bring valuable experience with them.","ru":"Многие пришедшие из других сфер приносят ценный опыт.","vi":"Nhiều người mới đến mang theo những kinh nghiệm quý báu.","fa":"بسیاری از تازه واردان تجربیات ارزشمندی را با خود به ارمغان می آورند."},{"de":"Der Seiteneinsteiger musste eine spezielle Ausbildung machen.","en":"The career changer had to do special training.","ru":"Ему пришлось пройти специальное обучение.","vi":"Người mới đến phải trải qua quá trình huấn luyện đặc biệt.","fa":"تازه وارد باید آموزش های ویژه ای را پشت سر می گذاشت."}]},{"word":"der Seitenspiegel","en":"side mirror, wing mirror","ru":"боковое зеркало (заднего вида)","vi":"gương bên","fa":"آینه بغل","examples":[{"de":"Vor dem Abbiegen schaute sie in den Seitenspiegel.","en":"Before turning, she looked in the wing mirror.","ru":"Перед поворотом она посмотрела в боковое зеркало.","vi":"Trước khi rẽ, cô nhìn vào gương bên.","fa":"قبل از اینکه بچرخد، به آینه بغل نگاه کرد."},{"de":"Der linke Seitenspiegel ist beim Parken abgebrochen.","en":"The left wing mirror broke off while parking.","ru":"При парковке отломилось левое боковое зеркало.","vi":"Gương bên trái bị vỡ khi đỗ xe.","fa":"آینه سمت چپ در حین پارک پاره شد."},{"de":"Stell den Seitenspiegel richtig ein, bevor du losfährst.","en":"Adjust the side mirror properly before you set off.","ru":"Правильно отрегулируй боковое зеркало, прежде чем тронуться.","vi":"Điều chỉnh gương chiếu hậu chính xác trước khi lái xe.","fa":"قبل از رانندگی آینه بغل را به درستی تنظیم کنید."}]},{"word":"der Sekretär","en":"secretary","ru":"секретарь","vi":"thư ký","fa":"منشی","examples":[{"de":"Der Sekretär organisiert alle Termine des Chefs.","en":"The secretary organizes all the boss's appointments.","ru":"Секретарь организует все встречи начальника.","vi":"Thư ký sắp xếp mọi cuộc hẹn của sếp.","fa":"منشی همه قرارهای رئیس را سازماندهی می کند."},{"de":"Er arbeitet seit fünf Jahren als Sekretär in dieser Firma.","en":"He has been working as a secretary at this company for five years.","ru":"Он уже пять лет работает секретарём в этой фирме.","vi":"Anh ấy đã làm thư ký ở công ty này được 5 năm.","fa":"او پنج سال است که به عنوان منشی در این شرکت مشغول به کار است."}]},{"word":"selb","en":"same (as in derselbe, am selben Tag)","ru":"тот же самый (как в derselbe, am selben Tag)","vi":"chính bạn","fa":"خودت","examples":[{"de":"Wir wohnen im selben Haus.","en":"We live in the same house.","ru":"Мы живём в одном и том же доме.","vi":"Chúng tôi sống trong cùng một ngôi nhà.","fa":"ما در یک خانه زندگی می کنیم."},{"de":"Sie kamen am selben Tag an.","en":"They arrived on the same day.","ru":"Они приехали в один и тот же день.","vi":"Họ đến vào cùng ngày.","fa":"در همان روز رسیدند."},{"de":"Er trägt jeden Tag denselben Pullover.","en":"He wears the same jumper every day.","ru":"Он каждый день носит один и тот же свитер.","vi":"Anh ấy mặc cùng một chiếc áo len mỗi ngày.","fa":"او هر روز همان ژاکت را می پوشد."}]},{"word":"selb-","en":"same (the same)","ru":"тот же самый","vi":"tự","fa":"خود","examples":[{"de":"Wir wohnen im selben Haus wie meine Eltern.","en":"We live in the same house as my parents.","ru":"Мы живём в том же доме, что и мои родители.","vi":"Chúng tôi sống cùng nhà với bố mẹ tôi.","fa":"ما با پدر و مادرم در یک خانه زندگی می کنیم."},{"de":"Er trägt jeden Tag dasselbe T-Shirt.","en":"He wears the same T-shirt every day.","ru":"Он каждый день носит одну и ту же футболку.","vi":"Anh ấy mặc cùng một chiếc áo phông mỗi ngày.","fa":"او هر روز همان تی شرت را می پوشد."}]},{"word":"selber","en":"(one)self, oneself (colloquial for selbst)","ru":"сам, самостоятельно (разг. от selbst)","vi":"chính bạn","fa":"خودت","examples":[{"de":"Das habe ich ganz selber gemacht.","en":"I did that all by myself.","ru":"Я сделал это совсем сам.","vi":"Tôi đã làm điều này hoàn toàn bản thân mình.","fa":"من این کار را کاملاً خودم انجام دادم."},{"de":"Du musst die Aufgabe selber lösen.","en":"You have to solve the task yourself.","ru":"Тебе надо решить задачу самому.","vi":"Bạn phải tự mình giải quyết nhiệm vụ.","fa":"شما باید خودتان کار را حل کنید."},{"de":"Er kocht sein Essen lieber selber.","en":"He prefers to cook his food himself.","ru":"Он предпочитает готовить еду сам.","vi":"Anh ấy thích tự nấu đồ ăn hơn.","fa":"او ترجیح می دهد غذای خود را بپزد."}]},{"word":"selbst","en":"oneself; even","ru":"сам; даже","vi":"chính bạn","fa":"خودت","examples":[{"de":"Ich habe den Kuchen selbst gebacken.","en":"I baked the cake myself.","ru":"Я сам испёк торт.","vi":"Tôi tự tay nướng bánh.","fa":"کیک رو خودم پختم"},{"de":"Selbst mein Vater konnte die Aufgabe nicht lösen.","en":"Even my father couldn't solve the task.","ru":"Даже мой отец не смог решить эту задачу.","vi":"Ngay cả bố tôi cũng không thể giải quyết được vấn đề.","fa":"حتی پدرم هم نتوانست مشکل را حل کند."}]},{"word":"selbständig","en":"self-employed; independent","ru":"самостоятельный; работающий на себя","vi":"độc lập","fa":"به طور مستقل","examples":[{"de":"Ein Selbständiger zahlt seine Steuern selbst.","en":"A self-employed person pays their own taxes.","ru":"Работающий на себя сам платит налоги.","vi":"Một người tự làm chủ tự trả thuế.","fa":"یک فرد خوداشتغال مالیات خود را پرداخت می کند."},{"de":"Seit zwei Jahren ist sie selbständig und führt ihr eigenes Café.","en":"She has been self-employed for two years and runs her own café.","ru":"Уже два года она работает на себя и держит собственное кафе.","vi":"Cô đã tự kinh doanh được hai năm và điều hành quán cà phê của riêng mình.","fa":"او دو سال است که شغل آزاد دارد و کافه خود را اداره می کند."},{"de":"Mein Sohn ist schon sehr selbständig und macht alles allein.","en":"My son is already very independent and does everything by himself.","ru":"Мой сын уже очень самостоятельный и всё делает сам.","vi":"Con trai tôi vốn đã rất độc lập và tự mình làm mọi việc.","fa":"پسر من در حال حاضر بسیار مستقل است و همه چیز را خودش انجام می دهد."}]},{"word":"die Selbstbeteiligung","en":"excess, deductible (insurance)","ru":"франшиза (в страховании), доля собственного участия","vi":"khoản khấu trừ","fa":"کسر","examples":[{"de":"Bei dieser Versicherung beträgt die Selbstbeteiligung 300 Euro.","en":"With this insurance the excess is 300 euros.","ru":"По этой страховке франшиза составляет 300 евро.","vi":"Với bảo hiểm này, khoản khấu trừ là 300 euro.","fa":"با این بیمه فرانشیز 300 یورو است."},{"de":"Eine hohe Selbstbeteiligung senkt den monatlichen Beitrag.","en":"A high deductible lowers the monthly premium.","ru":"Высокая франшиза снижает ежемесячный взнос.","vi":"Mức khấu trừ cao làm giảm phí bảo hiểm hàng tháng.","fa":"فرانشیز بالا حق بیمه ماهانه را کاهش می دهد."},{"de":"Die Selbstbeteiligung müssen Sie selbst zahlen.","en":"You have to pay the excess yourself.","ru":"Франшизу вы должны оплачивать сами.","vi":"Bạn phải tự mình trả khoản khấu trừ.","fa":"فرانشیز را خودتان باید پرداخت کنید."}]},{"word":"selbstständig","en":"independent","ru":"самостоятельный","vi":"độc lập","fa":"مستقل","examples":[{"de":"Meine Tochter ist schon sehr selbstständig für ihr Alter.","en":"My daughter is already very independent for her age.","ru":"Моя дочь уже очень самостоятельна для своего возраста.","vi":"Con gái tôi vốn đã rất tự lập so với tuổi của nó.","fa":"دخترم نسبت به سنش خیلی مستقل است."},{"de":"Er möchte sich beruflich selbstständig machen.","en":"He wants to become self-employed.","ru":"Он хочет стать самостоятельным предпринимателем.","vi":"Anh ấy muốn trở thành người tự kinh doanh.","fa":"او می خواهد خوداشتغالی شود."}]},{"word":"selbstverständlich","en":"of course; naturally","ru":"само собой разумеется; конечно","vi":"tất nhiên","fa":"البته","examples":[{"de":"Selbstverständlich helfe ich dir bei den Hausaufgaben.","en":"Of course I will help you with your homework.","ru":"Конечно, я помогу тебе с домашним заданием.","vi":"Tất nhiên là tôi sẽ giúp bạn làm bài tập về nhà.","fa":"البته من در انجام تکالیف به شما کمک خواهم کرد."},{"de":"Es ist für mich selbstverständlich, pünktlich zu sein.","en":"It is a matter of course for me to be punctual.","ru":"Для меня само собой разумеется быть пунктуальным.","vi":"Việc tôi đến đúng giờ là điều đương nhiên.","fa":"طبیعی است که به موقع بروم."}]},{"word":"selten","en":"rare; rarely","ru":"редкий; редко","vi":"hiếm","fa":"نادر","examples":[{"de":"Ein so schönes Wetter ist im November selten.","en":"Such nice weather is rare in November.","ru":"Такая хорошая погода редка в ноябре.","vi":"Thời tiết đẹp như vậy hiếm có vào tháng 11.","fa":"چنین هوای زیبایی در ماه نوامبر نادر است."},{"de":"Wir sehen uns nur noch selten.","en":"We only rarely see each other anymore.","ru":"Мы теперь видимся только редко.","vi":"Chúng tôi hiếm khi gặp nhau nữa.","fa":"ما دیگر به ندرت همدیگر را می بینیم."}]},{"word":"seltsam","en":"strange","ru":"странный","vi":"kỳ lạ","fa":"عجیب","examples":[{"de":"Er hat sich in letzter Zeit sehr seltsam benommen.","en":"He has behaved very strangely lately.","ru":"В последнее время он вёл себя очень странно.","vi":"Gần đây anh ấy cư xử rất lạ.","fa":"او اخیراً بسیار عجیب رفتار می کند."},{"de":"Das war ein seltsames Geräusch aus dem Keller.","en":"That was a strange noise from the basement.","ru":"Это был странный звук из подвала.","vi":"Đó là một tiếng động lạ phát ra từ tầng hầm.","fa":"صدای عجیبی از زیرزمین می آمد."}]},{"word":"das Semester","en":"semester","ru":"семестр","vi":"học kỳ","fa":"ترم","examples":[{"de":"Das neue Semester beginnt im Oktober.","en":"The new semester begins in October.","ru":"Новый семестр начинается в октябре.","vi":"Học kỳ mới bắt đầu vào tháng 10.","fa":"ترم جدید در ماه اکتبر شروع می شود."},{"de":"Sie studiert im dritten Semester Medizin.","en":"She is studying medicine in her third semester.","ru":"Она учится на третьем семестре медицины.","vi":"Cô ấy đang học y khoa trong học kỳ thứ ba.","fa":"او در ترم سوم پزشکی تحصیل می کند."}]},{"word":"das Seminar","en":"seminar","ru":"семинар","vi":"hội thảo","fa":"سمینار","examples":[{"de":"Ich besuche jede Woche ein Seminar an der Universität.","en":"I attend a seminar at the university every week.","ru":"Я каждую неделю посещаю семинар в университете.","vi":"Tôi tham dự một buổi hội thảo tại trường đại học mỗi tuần.","fa":"من هر هفته در یک سمینار در دانشگاه شرکت می کنم."},{"de":"Das Seminar zum Thema Kommunikation war sehr hilfreich.","en":"The seminar on the topic of communication was very helpful.","ru":"Семинар на тему общения был очень полезен.","vi":"Buổi hội thảo về giao tiếp rất hữu ích.","fa":"سمینار ارتباطات بسیار مفید بود."}]},{"word":"die Semmel","en":"bread roll (Austrian)","ru":"булочка (австр.)","vi":"cuộn","fa":"رول","examples":[{"de":"Zum Frühstück essen wir gern frische Semmeln.","en":"For breakfast, we like to eat fresh bread rolls.","ru":"На завтрак мы любим есть свежие булочки.","vi":"Chúng tôi thích ăn bánh mì tươi vào bữa sáng.","fa":"ما دوست داریم برای صبحانه رول های تازه بخوریم."},{"de":"Ich kaufe jeden Morgen Semmeln beim Bäcker.","en":"I buy bread rolls at the bakery every morning.","ru":"Я каждое утро покупаю булочки в пекарне.","vi":"Tôi mua bánh mì ở tiệm bánh vào mỗi buổi sáng.","fa":"من هر روز صبح از نانوایی رول می خرم."}]},{"word":"senden","en":"to send; to broadcast","ru":"отправлять; транслировать","vi":"gửi","fa":"ارسال کنید","examples":[{"de":"Ich sende dir die Dokumente per E-Mail.","en":"I will send you the documents by email.","ru":"Я отправлю тебе документы по электронной почте.","vi":"Tôi sẽ gửi tài liệu cho bạn qua email.","fa":"من مدارک را از طریق ایمیل برای شما ارسال می کنم."},{"de":"Das Fernsehen sendet heute Abend ein wichtiges Fußballspiel.","en":"The TV is broadcasting an important football match tonight.","ru":"Телевидение сегодня вечером транслирует важный футбольный матч.","vi":"TV đang phát sóng một trận bóng đá quan trọng tối nay.","fa":"تلویزیون امشب یک بازی مهم فوتبال را پخش می کند."}]},{"word":"der Sender","en":"(TV/radio) channel, broadcaster","ru":"(теле-/радио)канал, вещатель","vi":"máy phát","fa":"فرستنده","examples":[{"de":"Welcher Sender überträgt heute das Fußballspiel?","en":"Which channel is broadcasting the football match today?","ru":"По какому каналу сегодня показывают футбольный матч?","vi":"Hôm nay đài nào đang phát sóng trận bóng đá?","fa":"کدام شبکه امروز بازی فوتبال را پخش می کند؟"},{"de":"Ich schaue am liebsten öffentlich-rechtliche Sender.","en":"I prefer to watch public service channels.","ru":"Я предпочитаю смотреть общественные каналы.","vi":"Tôi thích xem các đài truyền hình công cộng hơn.","fa":"من تماشای پخش عمومی را ترجیح می دهم."},{"de":"Der Sender zeigt jeden Abend Nachrichten.","en":"The channel shows news every evening.","ru":"Канал показывает новости каждый вечер.","vi":"Đài này chiếu tin tức vào mỗi buổi tối.","fa":"این ایستگاه هر شب اخبار را نشان می دهد."}]},{"word":"die Sendung","en":"programme; broadcast","ru":"передача; программа","vi":"chương trình phát sóng","fa":"پخش","examples":[{"de":"Diese Sendung läuft jeden Sonntagabend.","en":"This programme is on every Sunday evening.","ru":"Эта передача выходит каждый воскресный вечер.","vi":"Chương trình này diễn ra vào tối chủ nhật hàng tuần.","fa":"این نمایش هر یکشنبه عصر اجرا می شود."},{"de":"Die Sendung über Tiere gefällt den Kindern sehr.","en":"The children really like the programme about animals.","ru":"Передача о животных очень нравится детям.","vi":"Các em rất thích chương trình biểu diễn về động vật.","fa":"بچه ها واقعاً نمایش حیوانات را دوست دارند."}]},{"word":"der Senior","en":"senior citizen (male)","ru":"пожилой человек, пенсионер (мужчина)","vi":"cấp trên","fa":"ارشد","examples":[{"de":"Der Kurs ist besonders für Senioren gedacht.","en":"The course is especially designed for senior citizens.","ru":"Курс специально рассчитан на пожилых людей.","vi":"Khóa học đặc biệt dành cho người cao tuổi.","fa":"این دوره به ویژه برای سالمندان در نظر گرفته شده است."},{"de":"Senioren bekommen im Museum eine Ermäßigung.","en":"Senior citizens get a discount at the museum.","ru":"Пожилые люди получают скидку в музее.","vi":"Người cao tuổi được giảm giá tại bảo tàng.","fa":"سالمندان در موزه تخفیف می گیرند."},{"de":"Mein Großvater ist ein sehr aktiver Senior.","en":"My grandfather is a very active senior citizen.","ru":"Мой дедушка — очень активный пожилой человек.","vi":"Ông tôi là một công dân cấp cao rất năng động.","fa":"پدربزرگ من یک شهروند سالخورده بسیار فعال است."}]},{"word":"die Senioren","en":"senior citizens","ru":"пожилые люди","vi":"người cao niên","fa":"سالمندان","examples":[{"de":"Im Park gibt es viele Bänke für Senioren.","en":"There are many benches for senior citizens in the park.","ru":"В парке много скамеек для пожилых людей.","vi":"Có rất nhiều ghế dài dành cho người cao tuổi trong công viên.","fa":"نیمکت های زیادی برای سالمندان در پارک وجود دارد."},{"de":"Das Zentrum bietet spezielle Kurse für Senioren an.","en":"The center offers special courses for senior citizens.","ru":"Центр предлагает специальные курсы для пожилых людей.","vi":"Trung tâm cung cấp các khóa học đặc biệt dành cho người cao tuổi.","fa":"این مرکز دوره های ویژه ای را برای سالمندان برگزار می کند."}]},{"word":"die Seniorin","en":"senior citizen (female)","ru":"пожилая женщина, пенсионерка","vi":"cấp trên","fa":"ارشد","examples":[{"de":"Die Seniorin wohnt allein in einer kleinen Wohnung.","en":"The senior citizen lives alone in a small flat.","ru":"Пожилая женщина живёт одна в маленькой квартире.","vi":"Người đàn ông lớn tuổi sống một mình trong một căn hộ nhỏ.","fa":"شهروند سالخورده به تنهایی در یک آپارتمان کوچک زندگی می کند."},{"de":"Eine freundliche Seniorin half mir am Bahnhof.","en":"A friendly senior citizen helped me at the station.","ru":"Приветливая пожилая женщина помогла мне на вокзале.","vi":"Một người phụ nữ lớn tuổi thân thiện đã giúp đỡ tôi ở ga xe lửa.","fa":"یک زن مسن دوست در ایستگاه قطار به من کمک کرد."},{"de":"Die Seniorin nimmt jeden Tag an der Gymnastik teil.","en":"The senior citizen takes part in the exercise class every day.","ru":"Пожилая женщина каждый день ходит на гимнастику.","vi":"Người cao tuổi tham gia thể dục dụng cụ mỗi ngày.","fa":"سالمند هر روز در ژیمناستیک شرکت می کند."}]},{"word":"senken","en":"to lower, to reduce","ru":"снижать, опускать","vi":"thấp hơn","fa":"پایین تر","examples":[{"de":"Die Firma will die Kosten senken.","en":"The company wants to reduce costs.","ru":"Компания хочет снизить расходы.","vi":"Công ty muốn giảm chi phí.","fa":"این شرکت می خواهد هزینه ها را کاهش دهد."},{"de":"Sie senkte verlegen den Kopf.","en":"She lowered her head in embarrassment.","ru":"Она смущённо опустила голову.","vi":"Cô xấu hổ cúi đầu xuống.","fa":"با خجالت سرش را پایین انداخت."},{"de":"Der Staat hat die Steuern gesenkt.","en":"The state has lowered taxes.","ru":"Государство снизило налоги.","vi":"Nhà nước đã giảm thuế.","fa":"دولت مالیات ها را کاهش داده است."}]},{"word":"senkrecht","en":"vertical","ru":"вертикальный","vi":"theo chiều dọc","fa":"عمودی","examples":[{"de":"Die Linie auf dem Papier muss senkrecht sein.","en":"The line on the paper must be vertical.","ru":"Линия на бумаге должна быть вертикальной.","vi":"Dòng trên giấy phải thẳng đứng.","fa":"خط روی کاغذ باید عمودی باشد."},{"de":"Der Fels fällt senkrecht ins Meer ab.","en":"The cliff drops vertically into the sea.","ru":"Скала обрывается вертикально в море.","vi":"Tảng đá rơi thẳng đứng xuống biển.","fa":"سنگ به صورت عمودی به دریا می ریزد."}]},{"word":"die Serie","en":"series","ru":"сериал; серия","vi":"loạt phim","fa":"سریال","examples":[{"de":"Meine Lieblingsserie kommt jeden Freitagabend im Fernsehen.","en":"My favorite series is on TV every Friday evening.","ru":"Мой любимый сериал показывают каждую пятницу вечером.","vi":"Bộ phim yêu thích của tôi được chiếu trên TV vào tối thứ Sáu hàng tuần.","fa":"سریال مورد علاقه من هر جمعه عصر از تلویزیون پخش می شود."},{"de":"Diese Serie hat schon sieben Staffeln.","en":"This series already has seven seasons.","ru":"У этого сериала уже семь сезонов.","vi":"This series has already had seven seasons.","fa":"این سریال قبلاً هفت فصل داشته است."}]},{"word":"der Server","en":"server","ru":"сервер","vi":"máy chủ","fa":"سرور","examples":[{"de":"Der Server ist seit heute Morgen nicht erreichbar.","en":"The server has been down since this morning.","ru":"Сервер недоступен с сегодняшнего утра.","vi":"Máy chủ không thể truy cập được kể từ sáng nay.","fa":"سرور از صبح امروز در دسترس نیست."},{"de":"Die Webseite ist langsam, weil der Server überlastet ist.","en":"The website is slow because the server is overloaded.","ru":"Сайт медленный, потому что сервер перегружен.","vi":"Trang web chậm do máy chủ quá tải.","fa":"وب سایت کند است زیرا سرور بیش از حد بارگذاری شده است."},{"de":"Alle Dateien liegen auf einem sicheren Server in Frankfurt.","en":"All the files are stored on a secure server in Frankfurt.","ru":"Все файлы лежат на защищённом сервере во Франкфурте.","vi":"Tất cả các tập tin đều nằm trên một máy chủ an toàn ở Frankfurt.","fa":"همه فایل ها در یک سرور امن در فرانکفورت هستند."}]},{"word":"der Service","en":"service","ru":"сервис, обслуживание","vi":"dịch vụ","fa":"خدمات","examples":[{"de":"Der Service in diesem Hotel ist ausgezeichnet.","en":"The service in this hotel is excellent.","ru":"Обслуживание в этом отеле превосходное.","vi":"Dịch vụ tại khách sạn này là tuyệt vời.","fa":"خدمات در این هتل عالی است."},{"de":"Wir haben uns über den freundlichen Service gefreut.","en":"We were pleased with the friendly service.","ru":"Мы были рады дружелюбному обслуживанию.","vi":"Chúng tôi hài lòng với dịch vụ thân thiện.","fa":"ما از خدمات دوستانه راضی بودیم."}]},{"word":"der Serviceangestellte","en":"service employee","ru":"сотрудник сферы обслуживания","vi":"nhân viên phục vụ","fa":"کارمند خدمات","examples":[{"de":"Der Serviceangestellte hat uns höflich geholfen.","en":"The service employee helped us politely.","ru":"Сотрудник обслуживания вежливо нам помог.","vi":"Nhân viên phục vụ lịch sự giúp đỡ chúng tôi.","fa":"کارمند خدمات مودبانه به ما کمک کرد."},{"de":"Als Serviceangestellter muss man freundlich zu den Kunden sein.","en":"As a service employee, you have to be friendly to customers.","ru":"Работая сотрудником сферы обслуживания, нужно быть вежливым с клиентами.","vi":"Là nhân viên phục vụ bạn phải thân thiện với khách hàng.","fa":"به عنوان یک کارمند خدمات باید با مشتریان دوستانه رفتار کنید."}]},{"word":"der Sessel","en":"armchair (Austrian: chair)","ru":"кресло","vi":"chiếc ghế bành","fa":"صندلی راحتی","examples":[{"de":"Er sitzt jeden Abend im Sessel und liest Zeitung.","en":"Every evening he sits in the armchair and reads the newspaper.","ru":"Каждый вечер он сидит в кресле и читает газету.","vi":"Anh ấy ngồi trên ghế bành mỗi tối và đọc báo.","fa":"هر روز غروب روی صندلی راحتی می نشیند و روزنامه می خواند."},{"de":"Der bequeme Sessel steht im Wohnzimmer.","en":"The comfortable armchair is in the living room.","ru":"Удобное кресло стоит в гостиной.","vi":"Chiếc ghế bành thoải mái được đặt trong phòng khách.","fa":"صندلی راحتی در اتاق نشیمن است."}]},{"word":"sich","en":"himself, herself, itself, themselves (reflexive pronoun)","ru":"себя, себе (возвратное местоимение)","vi":"chính bạn","fa":"خودت","examples":[{"de":"Er wäscht sich jeden Morgen kalt.","en":"He washes himself with cold water every morning.","ru":"Он каждое утро умывается холодной водой.","vi":"Anh ấy tắm rửa bằng nước lạnh mỗi sáng.","fa":"او هر روز صبح خود را در آب سرد شستشو می دهد."},{"de":"Die Kinder freuen sich auf die Ferien.","en":"The children are looking forward to the holidays.","ru":"Дети радуются каникулам.","vi":"Trẻ em đang mong chờ những ngày nghỉ lễ.","fa":"بچه ها مشتاقانه منتظر تعطیلات هستند."},{"de":"Sie hat sich gut auf die Prüfung vorbereitet.","en":"She prepared herself well for the exam.","ru":"Она хорошо подготовилась к экзамену.","vi":"Cô ấy đã chuẩn bị tốt cho kỳ thi.","fa":"او به خوبی برای امتحان آماده شد."}]},{"word":"sich amüsieren","en":"to enjoy oneself, to have fun","ru":"веселиться, развлекаться","vi":"chúc vui vẻ","fa":"خوش بگذره","examples":[{"de":"Die Kinder haben sich auf dem Fest prächtig amüsiert.","en":"The children had a wonderful time at the party.","ru":"Дети прекрасно повеселились на празднике.","vi":"The children had a great time at the festival.","fa":"بچه ها در جشنواره خیلی خوش گذشت."},{"de":"Wir haben uns gestern Abend im Kino sehr amüsiert.","en":"We had a lot of fun at the cinema last night.","ru":"Вчера вечером мы отлично повеселились в кино.","vi":"Wir haben uns gestern Abend im Kino sehr amüsiert.","fa":"دیشب در سینما خیلی خوش گذشت."}]},{"word":"sich anmelden","en":"to log in; to sign up","ru":"входить (в систему); регистрироваться","vi":"đăng nhập","fa":"وارد شوید","examples":[{"de":"Du musst dich zuerst mit deiner E-Mail anmelden.","en":"You first have to log in with your email.","ru":"Сначала тебе нужно войти с помощью своей электронной почты.","vi":"Trước tiên bạn phải đăng nhập bằng email của mình.","fa":"ابتدا باید با ایمیل خود وارد شوید."},{"de":"Ich kann mich nicht anmelden, das Passwort ist falsch.","en":"I can't log in, the password is wrong.","ru":"Я не могу войти, пароль неверный.","vi":"Tôi không thể đăng nhập, mật khẩu không đúng.","fa":"من نمی توانم وارد شوم، رمز عبور اشتباه است."},{"de":"Melde dich an, dann siehst du deine Daten.","en":"Log in and then you'll see your data.","ru":"Войди, тогда ты увидишь свои данные.","vi":"Đăng nhập và bạn sẽ thấy dữ liệu của bạn.","fa":"وارد شوید و اطلاعات خود را مشاهده خواهید کرد."}]},{"word":"sich anstrengen","en":"to make an effort, to try hard","ru":"стараться, прилагать усилия","vi":"nỗ lực","fa":"تلاش کن","examples":[{"de":"Du musst dich mehr anstrengen, um die Prüfung zu bestehen.","en":"You have to try harder to pass the exam.","ru":"Тебе нужно больше стараться, чтобы сдать экзамен.","vi":"Bạn phải cố gắng hơn nữa để vượt qua kỳ thi.","fa":"برای قبولی در امتحان باید بیشتر تلاش کنید."},{"de":"Sie strengte sich sehr an, pünktlich fertig zu werden.","en":"She made a great effort to finish on time.","ru":"Она очень старалась закончить вовремя.","vi":"Cô đã cố gắng rất nhiều để hoàn thành đúng thời hạn.","fa":"او خیلی تلاش کرد تا به موقع تمام شود."}]},{"word":"sich anziehen","en":"to get dressed","ru":"одеваться","vi":"mặc quần áo","fa":"لباس بپوش","examples":[{"de":"Zieh dich schnell an, wir müssen los!","en":"Get dressed quickly, we have to go!","ru":"Одевайся быстрее, нам пора идти!","vi":"Mặc quần áo nhanh lên, chúng ta phải đi!","fa":"سریع لباس بپوش، باید بریم!"},{"de":"Das Kind kann sich schon allein anziehen.","en":"The child can already get dressed by itself.","ru":"Ребёнок уже умеет одеваться самостоятельно.","vi":"Bé có thể tự mặc quần áo.","fa":"کودک می تواند خودش لباس بپوشد."}]},{"word":"sich ärgern","en":"to be annoyed, get angry","ru":"злиться, раздражаться","vi":"tức giận","fa":"عصبانی شدن","examples":[{"de":"Ich ärgere mich über den langsamen Internetanschluss.","en":"I'm annoyed about the slow internet connection.","ru":"Я злюсь из-за медленного интернет-соединения.","vi":"Tôi khó chịu vì kết nối internet chậm.","fa":"من از سرعت پایین اینترنت ناراحتم."},{"de":"Er ärgert sich, weil der Bus wieder Verspätung hat.","en":"He is annoyed because the bus is late again.","ru":"Он раздражается, потому что автобус снова опаздывает.","vi":"Er ärgert sich, weil der Bus wieder Verspätung hat.","fa":"او اذیت می شود چون اتوبوس دوباره دیر می شود."}]},{"word":"sich ausloggen","en":"to log out; separable verb (ich logge mich aus)","ru":"выходить (из системы), разлогиниваться; отделяемый глагол (ich logge mich aus)","vi":"đăng xuất","fa":"خروج از سیستم","examples":[{"de":"Vergiss nicht, dich am Ende wieder auszuloggen.","en":"Don't forget to log out again at the end.","ru":"Не забудь в конце снова выйти из системы.","vi":"Đừng quên đăng xuất lại vào cuối.","fa":"فراموش نکنید که در پایان دوباره از سیستم خارج شوید."},{"de":"Wenn du mit der Arbeit fertig bist, logg dich bitte aus.","en":"When you've finished your work, please log out.","ru":"Когда закончишь работу, пожалуйста, выйди из системы.","vi":"Khi bạn làm việc xong, vui lòng đăng xuất.","fa":"پس از پایان کار، لطفاً از سیستم خارج شوید."},{"de":"Ich habe mich aus Versehen ausgeloggt und muss mich neu anmelden.","en":"I logged out by accident and have to sign in again.","ru":"Я случайно вышел из системы и теперь должен войти заново.","vi":"Tôi vô tình đăng xuất và cần phải đăng nhập lại.","fa":"من به طور تصادفی از سیستم خارج شدم و باید دوباره وارد سیستم شوم."}]},{"word":"sich ausruhen","en":"to rest","ru":"отдыхать","vi":"nghỉ ngơi","fa":"برای استراحت","examples":[{"de":"Nach der langen Reise muss ich mich ausruhen.","en":"After the long journey I need to rest.","ru":"После долгого путешествия мне нужно отдохнуть.","vi":"Sau cuộc hành trình dài tôi cần phải nghỉ ngơi.","fa":"بعد از سفر طولانی نیاز به استراحت دارم."},{"de":"Setz dich hin und ruh dich ein bisschen aus.","en":"Sit down and rest a little.","ru":"Присядь и немного отдохни.","vi":"Sit down and rest a bit.","fa":"بنشین و کمی استراحت کن."}]},{"word":"sich bedanken","en":"to thank someone","ru":"благодарить","vi":"cảm ơn bạn","fa":"متشکرم","examples":[{"de":"Ich möchte mich bei Ihnen für die Hilfe bedanken.","en":"I would like to thank you for your help.","ru":"Я хотел бы поблагодарить вас за помощь.","vi":"Tôi muốn cảm ơn sự giúp đỡ của bạn.","fa":"من می خواهم از شما برای کمک تشکر کنم."},{"de":"Sie bedankte sich herzlich für das Geschenk.","en":"She thanked him warmly for the gift.","ru":"Она сердечно поблагодарила за подарок.","vi":"Cô cảm ơn anh rất nhiều vì món quà.","fa":"او از او برای هدیه بسیار تشکر کرد."}]},{"word":"sich beeilen","en":"to hurry","ru":"спешить, торопиться","vi":"nhanh lên","fa":"عجله کن","examples":[{"de":"Wir müssen uns beeilen, sonst verpassen wir den Zug.","en":"We have to hurry, or we'll miss the train.","ru":"Нам нужно поторопиться, иначе мы опоздаем на поезд.","vi":"Chúng ta phải nhanh lên nếu không chúng ta sẽ lỡ chuyến tàu.","fa":"باید عجله کنیم وگرنه قطار را از دست می دهیم."},{"de":"Beeil dich, das Essen wird kalt!","en":"Hurry up, the food is getting cold!","ru":"Поторопись, еда остывает!","vi":"Nhanh lên, đồ ăn sắp nguội rồi!","fa":"عجله کن غذا داره سرد میشه!"}]},{"word":"sich befinden","en":"to be located","ru":"находиться","vi":"được đặt","fa":"واقع شده اند","examples":[{"de":"Das Museum befindet sich im Stadtzentrum.","en":"The museum is located in the city center.","ru":"Музей находится в центре города.","vi":"Bảo tàng nằm ở trung tâm thành phố.","fa":"این موزه در مرکز شهر واقع شده است."},{"de":"Wo befindet sich der nächste Bahnhof?","en":"Where is the nearest train station located?","ru":"Где находится ближайший вокзал?","vi":"Ga xe lửa gần nhất ở đâu?","fa":"نزدیکترین ایستگاه قطار کجاست؟"}]},{"word":"sich bemühen","en":"to make an effort, try hard","ru":"стараться","vi":"nỗ lực","fa":"تلاش کن","examples":[{"de":"Ich bemühe mich, jeden Tag Deutsch zu üben.","en":"I make an effort to practice German every day.","ru":"Я стараюсь заниматься немецким каждый день.","vi":"Tôi cố gắng luyện tập tiếng Đức mỗi ngày.","fa":"سعی می کنم هر روز آلمانی تمرین کنم."},{"de":"Sie bemüht sich sehr um gute Noten.","en":"She tries very hard to get good grades.","ru":"Она очень старается получить хорошие оценки.","vi":"Cô ấy cố gắng rất nhiều để đạt được điểm cao.","fa":"او خیلی تلاش می کند تا نمرات خوبی بگیرد."}]},{"word":"sich beschweren","en":"to complain","ru":"жаловаться","vi":"phàn nàn","fa":"شکایت کردن","examples":[{"de":"Der Gast beschwerte sich über den Lärm.","en":"The guest complained about the noise.","ru":"Гость пожаловался на шум.","vi":"Khách phàn nàn về tiếng ồn.","fa":"مهمان از سر و صدا شکایت کرد."},{"de":"Ich möchte mich über den schlechten Service beschweren.","en":"I would like to complain about the poor service.","ru":"Я хотел бы пожаловаться на плохое обслуживание.","vi":"Tôi muốn phàn nàn về dịch vụ kém.","fa":"من می خواهم از خدمات ضعیف شکایت کنم."}]},{"word":"sich beteiligen","en":"to participate, take part","ru":"участвовать","vi":"tham gia","fa":"شرکت کنند","examples":[{"de":"Viele Studenten beteiligen sich an der Diskussion.","en":"Many students take part in the discussion.","ru":"Многие студенты участвуют в дискуссии.","vi":"Nhiều sinh viên tham gia thảo luận.","fa":"بسیاری از دانش آموزان در بحث شرکت می کنند."},{"de":"Ich möchte mich an dem Projekt beteiligen.","en":"I would like to participate in the project.","ru":"Я хотел бы принять участие в проекте.","vi":"Tôi muốn tham gia vào dự án.","fa":"من دوست دارم در پروژه شرکت کنم."}]},{"word":"sich bewerben","en":"to apply (for a job)","ru":"подавать заявку, претендовать (на работу)","vi":"áp dụng","fa":"اعمال شود","examples":[{"de":"Ich habe mich um eine Stelle als Lehrer beworben.","en":"I applied for a position as a teacher.","ru":"Я подал заявку на должность учителя.","vi":"Tôi đã nộp đơn xin việc làm giáo viên.","fa":"من برای شغل معلمی درخواست دادم."},{"de":"Viele Studenten bewerben sich um dieses Stipendium.","en":"Many students apply for this scholarship.","ru":"Многие студенты подают заявки на эту стипендию.","vi":"Rất nhiều sinh viên nộp đơn xin học bổng này.","fa":"بسیاری از دانشجویان برای این بورسیه درخواست می کنند."}]},{"word":"sich bewerben um","en":"to apply for","ru":"подавать заявку на, претендовать на (должность)","vi":"nộp đơn xin","fa":"درخواست کنید","examples":[{"de":"Ich möchte mich um diese Stelle bewerben.","en":"I would like to apply for this position.","ru":"Я хотел бы претендовать на эту должность.","vi":"Tôi muốn ứng tuyển vào vị trí này.","fa":"من می خواهم برای این موقعیت اقدام کنم."},{"de":"Sie hat sich um ein Stipendium beworben.","en":"She applied for a scholarship.","ru":"Она подала заявку на стипендию.","vi":"Cô ấy đã nộp đơn xin học bổng.","fa":"او برای بورسیه درخواست کرد."},{"de":"Um welchen Job hast du dich beworben?","en":"Which job did you apply for?","ru":"На какую работу ты подавал заявку?","vi":"Bạn đã ứng tuyển vào công việc nào?","fa":"برای کدام شغل درخواست دادید؟"}]},{"word":"sich duschen","en":"to shower","ru":"принимать душ","vi":"đi tắm","fa":"دوش بگیر","examples":[{"de":"Ich dusche mich jeden Morgen kalt.","en":"I take a cold shower every morning.","ru":"Я каждое утро принимаю холодный душ.","vi":"Tôi tắm nước lạnh vào mỗi buổi sáng.","fa":"من هر روز صبح دوش آب سرد میگیرم."},{"de":"Nach dem Training duscht er sich sofort.","en":"After training he showers immediately.","ru":"После тренировки он сразу принимает душ.","vi":"Sau khi tập luyện, anh ấy đi tắm ngay lập tức.","fa":"بعد از تمرین بلافاصله دوش می گیرد."}]},{"word":"sich eignen","en":"to be suitable","ru":"подходить, годиться","vi":"phù hợp","fa":"مناسب هستند","examples":[{"de":"Dieser Stoff eignet sich gut für Sommerkleidung.","en":"This fabric is well suited for summer clothing.","ru":"Эта ткань хорошо подходит для летней одежды.","vi":"Loại vải này rất tốt cho quần áo mùa hè.","fa":"این پارچه برای لباس های تابستانی مناسب است."},{"de":"Er eignet sich nicht für diesen Job.","en":"He is not suited for this job.","ru":"Он не подходит для этой работы.","vi":"Anh ấy không phù hợp với công việc này.","fa":"او برای این کار مناسب نیست"}]},{"word":"sich einigen","en":"to agree, to come to an agreement","ru":"договариваться","vi":"đồng ý","fa":"موافق","examples":[{"de":"Die beiden Firmen haben sich auf einen Preis geeinigt.","en":"The two companies agreed on a price.","ru":"Обе компании договорились о цене.","vi":"Hai công ty đã thống nhất được giá cả.","fa":"دو شرکت بر سر قیمت به توافق رسیده اند."},{"de":"Wir konnten uns nicht einigen, wohin wir fahren.","en":"We couldn't agree on where to go.","ru":"Мы не смогли договориться, куда поехать.","vi":"Chúng tôi không thể đồng ý về nơi sẽ đi.","fa":"نمی توانستیم به توافق برسیم که کجا برویم."}]},{"word":"sich einloggen","en":"to log in; separable verb (ich logge mich ein)","ru":"входить (в систему), логиниться; отделяемый глагол (ich logge mich ein)","vi":"đăng nhập","fa":"وارد شوید","examples":[{"de":"Dann kannst du dich einloggen und wieder ausloggen.","en":"Then you can log in and log out again.","ru":"Потом можно войти и снова выйти.","vi":"Sau đó, bạn có thể đăng nhập và đăng xuất lại.","fa":"سپس می توانید وارد شوید و دوباره از سیستم خارج شوید."},{"de":"Mit deinem Benutzernamen und Passwort kannst du dich jederzeit einloggen.","en":"With your username and password you can log in at any time.","ru":"С именем пользователя и паролем ты можешь войти в любой момент.","vi":"Bạn có thể đăng nhập bất cứ lúc nào bằng tên người dùng và mật khẩu của bạn.","fa":"شما می توانید در هر زمان با نام کاربری و رمز عبور خود وارد شوید."},{"de":"Ich konnte mich heute Morgen nicht einloggen, weil der Server down war.","en":"I couldn't log in this morning because the server was down.","ru":"Сегодня утром я не смог войти, потому что сервер не работал.","vi":"Sáng nay tôi không thể đăng nhập vì máy chủ bị hỏng.","fa":"امروز صبح نتونستم وارد بشم چون سرور قطع شده بود."}]},{"word":"sich entschließen","en":"to decide, make up one's mind","ru":"решиться, принять решение","vi":"quyết định","fa":"تصمیم بگیرند","examples":[{"de":"Nach langem Überlegen entschloss sie sich, das Studium zu wechseln.","en":"After much thought, she decided to change her studies.","ru":"После долгих раздумий она решилась сменить учёбу.","vi":"Sau nhiều cân nhắc, cô quyết định thay đổi việc học.","fa":"او پس از بررسی های زیاد تصمیم گرفت که درسش را تغییر دهد."},{"de":"Wir haben uns entschlossen, umzuziehen.","en":"We have decided to move.","ru":"Мы решились переехать.","vi":"Chúng tôi đã quyết định di chuyển.","fa":"ما تصمیم گرفته ایم که حرکت کنیم."}]},{"word":"sich entschuldigen","en":"to apologise","ru":"извиняться, просить прощения","vi":"xin lỗi","fa":"عذرخواهی کن","examples":[{"de":"Du solltest dich bei ihr entschuldigen.","en":"You should apologise to her.","ru":"Тебе следует перед ней извиниться.","vi":"Bạn nên xin lỗi cô ấy.","fa":"باید ازش عذرخواهی کنی"},{"de":"Er entschuldigte sich für die Verspätung.","en":"He apologised for the delay.","ru":"Он извинился за опоздание.","vi":"Anh xin lỗi vì sự chậm trễ.","fa":"او بابت تاخیر عذرخواهی کرد."},{"de":"Ich möchte mich aufrichtig entschuldigen.","en":"I would like to apologise sincerely.","ru":"Я хочу искренне извиниться.","vi":"Tôi muốn gửi lời xin lỗi chân thành.","fa":"من می خواهم از صمیم قلب عذرخواهی کنم."}]},{"word":"sich entwickeln","en":"to develop; to evolve","ru":"развиваться","vi":"phát triển","fa":"توسعه دهد","examples":[{"de":"Die Stadt hat sich in zehn Jahren stark entwickelt.","en":"The city has developed a lot in ten years.","ru":"Город сильно изменился за десять лет.","vi":"Thành phố đã phát triển rất nhiều trong mười năm.","fa":"این شهر در ده سال پیشرفت زیادی کرده است."},{"de":"Das Kind entwickelt sich ganz normal.","en":"The child is developing quite normally.","ru":"Ребёнок развивается совершенно нормально.","vi":"Bé đang phát triển bình thường.","fa":"کودک در حال رشد طبیعی است."}]},{"word":"sich erholen","en":"to recover; to relax","ru":"отдыхать, восстанавливаться","vi":"phục hồi","fa":"بهبود می یابند","examples":[{"de":"Nach der Krankheit musste er sich lange erholen.","en":"After the illness he had to recover for a long time.","ru":"После болезни ему пришлось долго восстанавливаться.","vi":"Sau cơn bệnh, anh phải hồi phục một thời gian dài.","fa":"پس از این بیماری او برای مدت طولانی مجبور به بهبودی شد."},{"de":"Im Urlaub kann man sich gut erholen.","en":"On vacation you can relax well.","ru":"В отпуске можно хорошо отдохнуть.","vi":"Bạn có thể thư giãn tốt trong kỳ nghỉ.","fa":"در تعطیلات می توانید به خوبی استراحت کنید."}]},{"word":"sich erkälten","en":"to catch a cold","ru":"простудиться","vi":"bị cảm lạnh","fa":"سرماخوردگی","examples":[{"de":"Zieh dich warm an, sonst erkältest du dich.","en":"Dress warmly, otherwise you'll catch a cold.","ru":"Одевайся теплее, иначе простудишься.","vi":"Mặc ấm vào nếu không bạn sẽ bị cảm lạnh đấy.","fa":"لباس گرم بپوشید وگرنه سرما می خورید."},{"de":"Ich habe mich letzte Woche erkältet.","en":"I caught a cold last week.","ru":"На прошлой неделе я простудился.","vi":"Tôi bị cảm lạnh tuần trước.","fa":"هفته پیش سرما خوردم"}]},{"word":"sich erkundigen","en":"to inquire, ask about","ru":"справляться, узнавать (информацию)","vi":"hỏi thăm","fa":"پرس و جو کنید","examples":[{"de":"Ich möchte mich nach den Öffnungszeiten erkundigen.","en":"I would like to inquire about the opening hours.","ru":"Я хотел бы узнать о часах работы.","vi":"Tôi muốn hỏi về thời gian mở cửa.","fa":"من می خواهم در مورد زمان باز کردن پرس و جو کنم."},{"de":"Er hat sich beim Arzt nach den Testergebnissen erkundigt.","en":"He inquired with the doctor about the test results.","ru":"Он справился у врача о результатах анализов.","vi":"Anh ấy hỏi bác sĩ về kết quả xét nghiệm.","fa":"او از دکتر در مورد نتایج آزمایش پرسید."}]},{"word":"(sich etwas) aussuchen","en":"to pick out, choose","ru":"выбирать (что-то себе)","vi":"chọn (cái gì đó).","fa":"انتخاب کردن (چیزی).","examples":[{"de":"Sie sucht sich ein schönes Kleid für die Party aus.","en":"She picks out a nice dress for the party.","ru":"Она выбирает себе красивое платье на вечеринку.","vi":"Cô chọn một chiếc váy đẹp cho bữa tiệc.","fa":"او یک لباس زیبا برای مهمانی انتخاب می کند."},{"de":"Such dir aus, welchen Film wir heute sehen wollen.","en":"Choose which movie we want to watch today.","ru":"Выбери, какой фильм мы посмотрим сегодня.","vi":"Hãy chọn bộ phim mà chúng ta muốn xem hôm nay.","fa":"انتخاب کنید کدام فیلم را امروز می خواهیم ببینیم."}]},{"word":"sich etwas gefallen lassen","en":"to put up with something, to tolerate something","ru":"мириться с чем-либо, терпеть что-либо","vi":"chịu đựng cái gì đó","fa":"تحمل کردن چیزی","examples":[{"de":"Ich lasse mir diese Unhöflichkeit nicht länger gefallen.","en":"I won't put up with this rudeness any longer.","ru":"Я больше не буду мириться с этой грубостью.","vi":"Tôi sẽ không chịu đựng sự thô lỗ này nữa.","fa":"من دیگر این بی ادبی را تحمل نمی کنم."},{"de":"Warum lässt du dir das gefallen?","en":"Why do you put up with that?","ru":"Почему ты это терпишь?","vi":"Tại sao bạn lại chịu đựng điều này?","fa":"چرا این را تحمل می کنید؟"}]},{"word":"sich etwas hinter die Ohren schreiben","en":"to make a mental note / remember something well","ru":"зарубить себе на носу","vi":"ghi nhớ/nhớ kỹ điều gì đó","fa":"یادداشت ذهنی کردن / چیزی را خوب به خاطر بسپارید","examples":[{"de":"Schreib dir das hinter die Ohren: Pünktlichkeit ist wichtig.","en":"Make a mental note of this: punctuality is important.","ru":"Заруби себе на носу: пунктуальность важна.","vi":"Hãy viết điều này sau tai bạn: đúng giờ là quan trọng.","fa":"این را پشت گوش خود بنویسید: وقت شناسی مهم است."}]},{"word":"(sich etwas) kaufen","en":"to buy (oneself something)","ru":"покупать (себе что-то)","vi":"mua (cái gì đó).","fa":"خرید (چیزی).","examples":[{"de":"Ich möchte mir ein neues Fahrrad kaufen.","en":"I want to buy myself a new bicycle.","ru":"Я хочу купить себе новый велосипед.","vi":"Tôi muốn mua một chiếc xe đạp mới.","fa":"من می خواهم یک دوچرخه جدید بخرم."},{"de":"Sie hat sich zum Geburtstag ein schönes Kleid gekauft.","en":"She bought herself a nice dress for her birthday.","ru":"Она купила себе красивое платье на день рождения.","vi":"Cô ấy đã mua cho mình một chiếc váy thật đẹp nhân dịp sinh nhật.","fa":"او برای تولدش یک لباس زیبا برای خودش خرید."}]},{"word":"sich freuen","en":"to be happy, look forward to","ru":"радоваться","vi":"hãy hạnh phúc","fa":"شاد باش","examples":[{"de":"Ich freue mich schon sehr auf die Ferien.","en":"I'm already really looking forward to the holidays.","ru":"Я уже очень жду каникул.","vi":"Tôi thực sự mong chờ những ngày nghỉ lễ.","fa":"من واقعاً منتظر تعطیلات هستم."},{"de":"Sie freute sich riesig über das Geschenk.","en":"She was overjoyed about the gift.","ru":"Она очень обрадовалась подарку.","vi":"Cô ấy rất vui về món quà.","fa":"او از این هدیه بسیار خوشحال شد."}]},{"word":"sich fürchten","en":"to be afraid","ru":"бояться","vi":"sợ hãi","fa":"بترس","examples":[{"de":"Kleine Kinder fürchten sich oft vor der Dunkelheit.","en":"Small children are often afraid of the dark.","ru":"Маленькие дети часто боятся темноты.","vi":"Trẻ nhỏ thường sợ bóng tối.","fa":"بچه های کوچک اغلب از تاریکی می ترسند."},{"de":"Ich fürchte mich vor Spinnen.","en":"I'm afraid of spiders.","ru":"Я боюсь пауков.","vi":"Tôi sợ nhện.","fa":"من از عنکبوت می ترسم"}]},{"word":"sich gewöhnen","en":"to get used to","ru":"привыкать","vi":"làm quen với","fa":"عادت کن","examples":[{"de":"An das frühe Aufstehen muss ich mich erst gewöhnen.","en":"I still have to get used to getting up early.","ru":"К раннему подъёму мне ещё нужно привыкнуть.","vi":"Tôi phải làm quen với việc dậy sớm.","fa":"باید به زود بیدار شدن عادت کنم."},{"de":"Nach einer Woche hatte ich mich an die neue Stadt gewöhnt.","en":"After a week I had got used to the new city.","ru":"Через неделю я привык к новому городу.","vi":"Sau một tuần tôi đã quen với thành phố mới.","fa":"بعد از یک هفته به شهر جدید عادت کردم."},{"de":"Man gewöhnt sich schnell an guten Kaffee.","en":"You quickly get used to good coffee.","ru":"К хорошему кофе быстро привыкаешь.","vi":"Bạn nhanh chóng làm quen với cà phê ngon.","fa":"به سرعت به قهوه خوب عادت می کنید."}]},{"word":"sich gewöhnen an","en":"to get used to","ru":"привыкать к (чему-либо)","vi":"làm quen với","fa":"عادت کن","examples":[{"de":"Man gewöhnt sich schnell an das neue Land.","en":"You quickly get used to the new country.","ru":"К новой стране быстро привыкаешь.","vi":"Bạn nhanh chóng làm quen với đất nước mới.","fa":"شما به سرعت به کشور جدید عادت می کنید."},{"de":"Ich kann mich nicht an die Kälte gewöhnen.","en":"I cannot get used to the cold.","ru":"Я не могу привыкнуть к холоду.","vi":"Tôi không thể quen với cái lạnh.","fa":"من نمی توانم به سرما عادت کنم."},{"de":"Sie gewöhnte sich an den frühen Tagesablauf.","en":"She got used to the early daily routine.","ru":"Она привыкла к раннему распорядку дня.","vi":"Cô đã quen với thói quen sớm hàng ngày.","fa":"او به کارهای روزمره اولیه عادت کرد."}]},{"word":"sich ins Zeug legen","en":"to put in a lot of effort / go all out","ru":"выкладываться, стараться изо всех сил","vi":"nỗ lực rất nhiều/ nỗ lực hết mình","fa":"تلاش زیادی کردن / تمام تلاش کردن","examples":[{"de":"Für die Prüfung hat sie sich richtig ins Zeug gelegt.","en":"She really went all out for the exam.","ru":"К экзамену она выложилась по-настоящему.","vi":"Cô ấy thực sự đã làm việc chăm chỉ cho kỳ thi.","fa":"او واقعا برای امتحان زحمت کشید."}]},{"word":"sich irren","en":"to be mistaken","ru":"ошибаться","vi":"sai","fa":"اشتباه کن","examples":[{"de":"Entschuldigung, ich habe mich geirrt, das ist die falsche Nummer.","en":"Sorry, I was mistaken, that's the wrong number.","ru":"Извините, я ошибся, это неправильный номер.","vi":"Xin lỗi, tôi nhầm, nhầm số rồi.","fa":"ببخشید اشتباه کردم، این شماره اشتباه است."},{"de":"Jeder kann sich mal irren.","en":"Everyone can be wrong sometimes.","ru":"Каждый может иногда ошибаться.","vi":"Mọi người đôi khi có thể sai.","fa":"همه ممکن است گاهی اشتباه کنند."}]},{"word":"sich konzentrieren","en":"to concentrate","ru":"концентрироваться, сосредотачиваться","vi":"tập trung","fa":"متمرکز کردن","examples":[{"de":"Ich kann mich bei Lärm nicht konzentrieren.","en":"I can't concentrate when there's noise.","ru":"Я не могу сосредоточиться при шуме.","vi":"Tôi không thể tập trung trong tiếng ồn.","fa":"من نمی توانم در سر و صدا تمرکز کنم."},{"de":"Konzentriere dich bitte auf die Aufgabe.","en":"Please concentrate on the task.","ru":"Пожалуйста, сосредоточься на задании.","vi":"Hãy tập trung vào nhiệm vụ.","fa":"لطفا روی کار تمرکز کنید"}]},{"word":"sich kümmern","en":"to take care of, look after","ru":"заботиться","vi":"chăm sóc","fa":"مراقبت از","examples":[{"de":"Sie kümmert sich liebevoll um ihre kranke Mutter.","en":"She lovingly takes care of her sick mother.","ru":"Она с любовью заботится о своей больной матери.","vi":"Cô tận tình chăm sóc người mẹ ốm yếu của mình.","fa":"او با عشق از مادر بیمارش مراقبت می کند."},{"de":"Wer kümmert sich um den Hund, wenn ihr im Urlaub seid?","en":"Who will take care of the dog while you're on vacation?","ru":"Кто позаботится о собаке, пока вы в отпуске?","vi":"Ai sẽ chăm sóc con chó khi bạn đi nghỉ?","fa":"وقتی در تعطیلات هستید چه کسی از سگ مراقبت می کند؟"}]},{"word":"sich langweilen","en":"to be bored","ru":"скучать","vi":"chán nản","fa":"خسته شدن","examples":[{"de":"Die Kinder langweilen sich im Regen.","en":"The children are bored in the rain.","ru":"Дети скучают под дождём.","vi":"Lũ trẻ buồn chán dưới mưa.","fa":"بچه ها زیر باران خسته شده اند."},{"de":"Ich habe mich auf der Party gelangweilt.","en":"I was bored at the party.","ru":"Мне было скучно на вечеринке.","vi":"Tôi cảm thấy chán ở bữa tiệc.","fa":"در مهمانی حوصله ام سر رفته بود."}]},{"word":"sich lohnen","en":"to be worth it","ru":"стоить (того); окупаться","vi":"đáng giá","fa":"ارزشش را دارد","examples":[{"de":"Es lohnt sich, früh aufzustehen und die Sonne zu sehen.","en":"It's worth getting up early to see the sun.","ru":"Стоит встать пораньше, чтобы увидеть солнце.","vi":"Thật đáng để dậy sớm và ngắm mặt trời.","fa":"ارزش این را دارد که زود بیدار شوید و خورشید را ببینید."},{"de":"Diese Investition hat sich wirklich gelohnt.","en":"This investment really paid off.","ru":"Эта инвестиция действительно окупилась.","vi":"Khoản đầu tư này thực sự đáng giá.","fa":"این سرمایه گذاری واقعا ارزشش را داشت."}]},{"word":"sich nähern","en":"to approach, to come closer","ru":"приближаться","vi":"cách tiếp cận","fa":"رویکرد","examples":[{"de":"Der Zug nähert sich langsam dem Bahnhof.","en":"The train is slowly approaching the station.","ru":"Поезд медленно приближается к вокзалу.","vi":"Con tàu đang dần tiến đến ga.","fa":"قطار کم کم به ایستگاه نزدیک می شود."},{"de":"Die Prüfung nähert sich, deshalb lerne ich jeden Tag.","en":"The exam is approaching, so I study every day.","ru":"Экзамен приближается, поэтому я занимаюсь каждый день.","vi":"Kỳ thi đang đến gần nên tôi học mỗi ngày.","fa":"امتحان نزدیک است، بنابراین من هر روز مطالعه می کنم."}]},{"word":"sich rasieren","en":"to shave (oneself)","ru":"бриться","vi":"tự cạo râu","fa":"خود را بتراش","examples":[{"de":"Mein Vater rasiert sich jeden Morgen.","en":"My father shaves every morning.","ru":"Мой отец бреется каждое утро.","vi":"Bố tôi cạo râu mỗi sáng.","fa":"پدرم هر روز صبح اصلاح می کند."},{"de":"Ich habe mich heute noch nicht rasiert.","en":"I haven't shaved yet today.","ru":"Я сегодня ещё не побрился.","vi":"Hôm nay tôi chưa cạo râu.","fa":"من امروز اصلاح نکردم"}]},{"word":"sich registrieren","en":"to register; to sign up for a service or network","ru":"регистрироваться, зарегистрироваться (в сервисе или сети)","vi":"đăng ký","fa":"ثبت نام کنید","examples":[{"de":"Um ein Konto zu eröffnen, muss man sich zuerst registrieren.","en":"To open an account, you first have to register.","ru":"Чтобы открыть аккаунт, нужно сначала зарегистрироваться.","vi":"Để mở tài khoản trước tiên bạn phải đăng ký.","fa":"برای افتتاح حساب ابتدا باید ثبت نام کنید."},{"de":"Bevor du die App nutzen kannst, musst du dich mit deiner E-Mail-Adresse registrieren.","en":"Before you can use the app, you have to register with your email address.","ru":"Прежде чем пользоваться приложением, нужно зарегистрироваться с помощью адреса электронной почты.","vi":"Trước khi có thể sử dụng ứng dụng, bạn phải đăng ký bằng địa chỉ email của mình.","fa":"قبل از اینکه بتوانید از برنامه استفاده کنید، باید با آدرس ایمیل خود ثبت نام کنید."},{"de":"Ich habe mich gestern für den Newsletter registriert.","en":"I signed up for the newsletter yesterday.","ru":"Я вчера подписался на рассылку.","vi":"Tôi đã đăng ký nhận bản tin ngày hôm qua.","fa":"من دیروز در خبرنامه ثبت نام کردم."}]},{"word":"sich scheiden lassen","en":"to get divorced","ru":"разводиться","vi":"ly hôn","fa":"طلاق گرفتن","examples":[{"de":"Meine Eltern haben sich vor zwei Jahren scheiden lassen.","en":"My parents got divorced two years ago.","ru":"Мои родители развелись два года назад.","vi":"Bố mẹ tôi ly hôn cách đây hai năm.","fa":"پدر و مادرم دو سال پیش طلاق گرفتند."},{"de":"Sie will sich von ihrem Mann scheiden lassen.","en":"She wants to divorce her husband.","ru":"Она хочет развестись с мужем.","vi":"Cô ấy muốn ly hôn với chồng.","fa":"او می خواهد از شوهرش طلاق بگیرد."}]},{"word":"sich schneiden","en":"to cut oneself","ru":"порезаться","vi":"cắt nhau","fa":"یکدیگر را قطع کنید","examples":[{"de":"Beim Kochen hat sie sich in den Finger geschnitten.","en":"While cooking, she cut her finger.","ru":"Готовя еду, она порезала палец.","vi":"Cô ấy bị đứt tay khi đang nấu ăn.","fa":"هنگام آشپزی انگشتش را برید."},{"de":"Pass auf, dass du dich mit dem Messer nicht schneidest.","en":"Be careful not to cut yourself with the knife.","ru":"Будь осторожен, не порежься ножом.","vi":"Hãy cẩn thận để không tự cắt mình bằng dao.","fa":"مراقب باشید خود را با چاقو نبرید."}]},{"word":"sich setzen","en":"to sit down","ru":"садиться","vi":"ngồi xuống","fa":"بنشین","examples":[{"de":"Bitte setzen Sie sich auf diesen Stuhl.","en":"Please sit down on this chair.","ru":"Пожалуйста, садитесь на этот стул.","vi":"Xin hãy ngồi lên chiếc ghế này.","fa":"لطفا روی این صندلی بنشینید"},{"de":"Er setzte sich neben seine Schwester.","en":"He sat down next to his sister.","ru":"Он сел рядом со своей сестрой.","vi":"Anh ngồi xuống cạnh em gái mình.","fa":"کنار خواهرش نشست."}]},{"word":"sich siezen","en":"to address each other formally (with \"Sie\")","ru":"обращаться друг к другу на «вы»","vi":"xưng hô trang trọng (dùng 'Sie')","fa":"با «شما» خطاب کردن","examples":[{"de":"Kollegen siezen sich in dieser Firma meistens.","en":"Colleagues usually address each other formally in this company.","ru":"Коллеги в этой фирме обычно обращаются друг к другу на «вы».","vi":"Đồng nghiệp chủ yếu ngồi cùng nhau trong công ty này.","fa":"همکاران بیشتر در این شرکت دور هم می نشینند."},{"de":"Sollen wir uns siezen oder duzen?","en":"Should we address each other formally or informally?","ru":"Нам обращаться друг к другу на «вы» или на «ты»?","vi":"Chúng ta nên sử dụng thuật ngữ tên riêng hay tên riêng?","fa":"آیا باید بر اساس اصطلاحات اسمی باشیم یا از نظر اسمی؟"}]},{"word":"sich stoßen","en":"to bump oneself; to knock (against something)","ru":"удариться (обо что-л.)","vi":"va vào nhau","fa":"به یکدیگر برخورد کنند","examples":[{"de":"Ich habe mich am Tisch gestoßen.","en":"I bumped myself on the table.","ru":"Я ударился о стол.","vi":"Tôi va vào bàn.","fa":"به میز برخورد کردم."},{"de":"Pass auf, dass du dir nicht den Kopf stößt.","en":"Watch out that you don't bump your head.","ru":"Смотри не ударься головой.","vi":"Hãy cẩn thận để không bị đánh vào đầu.","fa":"مواظب باش سرت نخورد."}]},{"word":"sich streiten","en":"to argue; to quarrel","ru":"ссориться; спорить","vi":"tranh luận","fa":"بحث کنید","examples":[{"de":"Die Geschwister streiten sich oft um das Spielzeug.","en":"The siblings often argue over the toy.","ru":"Братья и сёстры часто ссорятся из-за игрушки.","vi":"Hai anh em thường xuyên tranh nhau đồ chơi.","fa":"خواهر و برادر اغلب بر سر اسباب بازی با هم دعوا می کنند."},{"de":"Wir haben uns gestern über Politik gestritten.","en":"We argued about politics yesterday.","ru":"Мы вчера спорили о политике.","vi":"Hôm qua chúng tôi đã tranh luận về chính trị.","fa":"دیروز سر سیاست بحث کردیم."}]},{"word":"sich trennen","en":"to separate, to break up","ru":"расставаться, разводиться","vi":"riêng biệt","fa":"جدا کردن","examples":[{"de":"Meine Eltern haben sich vor zwei Jahren getrennt.","en":"My parents separated two years ago.","ru":"Мои родители расстались два года назад.","vi":"Bố mẹ tôi đã ly thân cách đây hai năm.","fa":"پدر و مادرم دو سال پیش از هم جدا شدند."},{"de":"Wir trennen uns hier, ich muss nach Hause.","en":"We part here, I have to go home.","ru":"Здесь мы расстаёмся, мне нужно домой.","vi":"Chúng ta chia tay ở đây, tôi phải về nhà.","fa":"اینجا داریم از هم جدا میشیم، باید برم خونه."}]},{"word":"sich überzeugen","en":"to convince oneself, make sure","ru":"убеждаться","vi":"thuyết phục bản thân","fa":"خودت را متقاعد کن","examples":[{"de":"Ich habe mich selbst von der Qualität überzeugt.","en":"I convinced myself of the quality.","ru":"Я сам убедился в качестве.","vi":"Tôi đã thuyết phục bản thân về chất lượng.","fa":"من خودم را به کیفیت متقاعد کردم."},{"de":"Überzeug dich am besten selbst davon.","en":"You'd best see for yourself.","ru":"Лучше убедись в этом сам.","vi":"Tốt nhất là bạn nên tự mình xem.","fa":"بهتر است خودتان ببینید."}]},{"word":"sich umdrehen","en":"to turn around","ru":"оборачиваться","vi":"quay lại","fa":"برگرد","examples":[{"de":"Sie drehte sich um und lächelte mich an.","en":"She turned around and smiled at me.","ru":"Она обернулась и улыбнулась мне.","vi":"Cô ấy quay lại và mỉm cười với tôi.","fa":"برگشت و به من لبخند زد."},{"de":"Dreh dich bitte nicht um!","en":"Please don't turn around!","ru":"Пожалуйста, не оборачивайся!","vi":"Làm ơn đừng quay lại!","fa":"لطفا برنگردید!"}]},{"word":"sich umziehen","en":"to change clothes","ru":"переодеваться","vi":"thay quần áo","fa":"لباس عوض کن","examples":[{"de":"Ich muss mich noch umziehen, bevor wir gehen.","en":"I still need to change clothes before we go.","ru":"Мне нужно ещё переодеться, прежде чем мы пойдём.","vi":"Tôi phải thay đồ trước khi chúng ta rời đi.","fa":"قبل از رفتن باید تغییر کنم."},{"de":"Zieh dich schnell um, wir sind spät dran!","en":"Change quickly, we're running late!","ru":"Быстро переоденься, мы опаздываем!","vi":"Mau thay đồ đi, chúng ta muộn rồi!","fa":"زود عوضش کن دیر رسیدیم"}]},{"word":"sich unterhalten","en":"to converse, chat","ru":"беседовать","vi":"trò chuyện","fa":"چت کنید","examples":[{"de":"Wir haben uns lange über Politik unterhalten.","en":"We talked for a long time about politics.","ru":"Мы долго беседовали о политике.","vi":"Chúng tôi đã nói chuyện rất lâu về chính trị.","fa":"ما مدت زیادی در مورد سیاست صحبت کردیم."},{"de":"Die beiden unterhalten sich sehr gern miteinander.","en":"The two of them really like chatting with each other.","ru":"Эти двое очень любят беседовать друг с другом.","vi":"Hai người họ thực sự rất thích nói chuyện với nhau.","fa":"آن دو واقعا از صحبت کردن با یکدیگر لذت می برند."}]},{"word":"sich verabreden","en":"to arrange to meet, make a date","ru":"договариваться о встрече","vi":"sắp xếp gặp nhau","fa":"قرار ملاقات","examples":[{"de":"Wir haben uns für morgen Abend verabredet.","en":"We arranged to meet tomorrow evening.","ru":"Мы договорились встретиться завтра вечером.","vi":"Chúng tôi đã sắp xếp để gặp nhau vào tối mai.","fa":"قرار گذاشتیم فردا عصر همدیگر را ببینیم."},{"de":"Ich habe mich mit einer Freundin zum Kaffee verabredet.","en":"I arranged to meet a friend for coffee.","ru":"Я договорилась встретиться с подругой за кофе.","vi":"Tôi hẹn gặp một người bạn để uống cà phê.","fa":"قرار گذاشتم برای قهوه با یکی از دوستانم ملاقات کنم."}]},{"word":"sich verabschieden","en":"to say goodbye","ru":"прощаться","vi":"nói lời tạm biệt","fa":"خداحافظی کن","examples":[{"de":"Wir haben uns herzlich voneinander verabschiedet.","en":"We said goodbye to each other warmly.","ru":"Мы тепло попрощались друг с другом.","vi":"Chúng tôi chào tạm biệt nhau một cách ấm áp.","fa":"به گرمی از هم خداحافظی کردیم."},{"de":"Ich muss mich jetzt verabschieden, mein Bus kommt gleich.","en":"I have to say goodbye now, my bus is coming soon.","ru":"Мне нужно попрощаться, мой автобус скоро придёт.","vi":"Bây giờ tôi phải nói lời tạm biệt, xe buýt của tôi sắp đến rồi.","fa":"الان باید خداحافظی کنم، اتوبوسم به زودی می آید."}]},{"word":"sich verändern","en":"to change","ru":"меняться, изменяться","vi":"thay đổi","fa":"تغییر دهید","examples":[{"de":"Die Stadt hat sich in den letzten Jahren stark verändert.","en":"The city has changed a lot in recent years.","ru":"Город сильно изменился за последние годы.","vi":"Thành phố đã thay đổi rất nhiều trong những năm gần đây.","fa":"این شهر در سال های اخیر تغییرات زیادی کرده است."},{"de":"Er hat sich seit der Schulzeit kaum verändert.","en":"He has hardly changed since school days.","ru":"Он почти не изменился со школьных времён.","vi":"Anh ấy không thay đổi nhiều kể từ khi còn đi học.","fa":"از زمانی که در مدرسه بوده تغییر چندانی نکرده است."}]},{"word":"sich verbessern","en":"to improve","ru":"улучшаться","vi":"cải thiện","fa":"بهبود بخشد","examples":[{"de":"Meine Deutschkenntnisse haben sich verbessert.","en":"My German skills have improved.","ru":"Мои знания немецкого улучшились.","vi":"Kỹ năng tiếng Đức của tôi đã được cải thiện.","fa":"مهارت های آلمانی من بهبود یافته است."},{"de":"Er möchte sich im Sport verbessern.","en":"He wants to improve in sports.","ru":"Он хочет улучшить свои результаты в спорте.","vi":"Anh ấy muốn tiến bộ trong thể thao.","fa":"او می خواهد در ورزش پیشرفت کند."}]},{"word":"sich verbrennen","en":"to burn oneself","ru":"обжигаться","vi":"đốt cháy chính mình","fa":"خودت را بسوزان","examples":[{"de":"Ich habe mir am Herd die Hand verbrannt.","en":"I burned my hand on the stove.","ru":"Я обжёг руку о плиту.","vi":"Tôi bị bỏng tay trên bếp.","fa":"دستم را روی اجاق گاز سوزاندم."},{"de":"Pass auf, dass du dich nicht verbrennst!","en":"Watch out that you don't burn yourself!","ru":"Смотри, не обожгись!","vi":"Hãy cẩn thận để không bị bỏng!","fa":"مواظب باش خودت نسوزی!"}]},{"word":"sich vergnügen","en":"to enjoy oneself, have fun","ru":"развлекаться, веселиться","vi":"chúc vui vẻ","fa":"خوش بگذره","examples":[{"de":"Die Kinder vergnügen sich am Strand mit einem Ball.","en":"The children enjoy themselves at the beach with a ball.","ru":"Дети развлекаются на пляже с мячом.","vi":"Trẻ em vui đùa với quả bóng trên bãi biển.","fa":"بچه ها با یک توپ در ساحل مشغول تفریح هستند."},{"de":"Wir haben uns auf dem Fest königlich vergnügt.","en":"We had a wonderful time at the party.","ru":"Мы прекрасно повеселились на празднике.","vi":"Chúng tôi đã có một thời gian tuyệt vời tại lễ hội.","fa":"در جشنواره به ما خوش گذشت."}]},{"word":"sich verhalten","en":"to behave","ru":"вести себя","vi":"cư xử","fa":"رفتار کن","examples":[{"de":"Die Schüler haben sich im Unterricht ruhig verhalten.","en":"The students behaved quietly during class.","ru":"Ученики вели себя спокойно на уроке.","vi":"Học sinh cư xử yên lặng trong lớp.","fa":"دانش آموزان در کلاس آرام رفتار می کردند."},{"de":"Wie soll man sich in einem Notfall verhalten?","en":"How should one behave in an emergency?","ru":"Как нужно вести себя в чрезвычайной ситуации?","vi":"Bạn nên cư xử thế nào trong trường hợp khẩn cấp?","fa":"در مواقع اضطراری چگونه باید رفتار کرد؟"}]},{"word":"sich verlassen","en":"to rely (on someone)","ru":"полагаться (на кого-либо)","vi":"tin cậy, dựa vào (ai đó)","fa":"تکیه کردن (به کسی)","examples":[{"de":"Auf ihn kann man sich immer verlassen.","en":"You can always rely on him.","ru":"На него всегда можно положиться.","vi":"Bạn luôn có thể dựa vào anh ấy.","fa":"همیشه می توانید به او تکیه کنید."},{"de":"Verlass dich nicht zu sehr auf dein Glück.","en":"Don't rely too much on your luck.","ru":"Не полагайся слишком на удачу.","vi":"Đừng dựa quá nhiều vào vận may của mình.","fa":"زیاد به شانس خود تکیه نکنید."}]},{"word":"sich verlaufen","en":"to get lost (on foot)","ru":"заблудиться","vi":"bị lạc","fa":"گم شدن","examples":[{"de":"Wir haben uns im Wald verlaufen.","en":"We got lost in the forest.","ru":"Мы заблудились в лесу.","vi":"Chúng tôi bị lạc trong rừng.","fa":"ما در جنگل گم شدیم."},{"de":"Ohne Karte hätte ich mich in der fremden Stadt verlaufen.","en":"Without a map I would have gotten lost in the unfamiliar city.","ru":"Без карты я бы заблудился в незнакомом городе.","vi":"Nếu không có bản đồ chắc tôi đã lạc vào thành phố xa lạ này.","fa":"بدون نقشه در شهر غریب گم می شدم."}]},{"word":"sich verletzen","en":"to injure oneself, get hurt","ru":"получить травму, пораниться","vi":"làm tổn thương chính mình","fa":"به خود صدمه بزن","examples":[{"de":"Beim Fußballspielen hat er sich am Bein verletzt.","en":"He injured his leg while playing football.","ru":"Играя в футбол, он повредил ногу.","vi":"Anh ấy bị thương ở chân khi chơi bóng đá.","fa":"او در حین بازی فوتبال از ناحیه پای خود آسیب دید."},{"de":"Pass auf, dass du dich mit dem Messer nicht verletzt.","en":"Be careful not to hurt yourself with the knife.","ru":"Осторожно, не пораньтесь ножом.","vi":"Hãy cẩn thận để không làm tổn thương chính mình bằng con dao.","fa":"مراقب باشید با چاقو به خودتان آسیب نزنید."}]},{"word":"sich verlieben","en":"to fall in love","ru":"влюбиться","vi":"yêu","fa":"عاشق شدن","examples":[{"de":"Sie hat sich auf den ersten Blick in ihn verliebt.","en":"She fell in love with him at first sight.","ru":"Она влюбилась в него с первого взгляда.","vi":"Cô đã yêu anh ngay từ cái nhìn đầu tiên.","fa":"در همان نگاه اول عاشق او شد."},{"de":"Die beiden haben sich im Urlaub ineinander verliebt.","en":"The two fell in love with each other during the vacation.","ru":"Они влюбились друг в друга во время отпуска.","vi":"Hai người yêu nhau khi đi nghỉ.","fa":"این دو در تعطیلات عاشق یکدیگر شدند."}]},{"word":"sich vernetzen","en":"to network or connect with others online","ru":"налаживать связи, устанавливать контакты (в интернете)","vi":"mạng lưới","fa":"شبکه","examples":[{"de":"So kann man sich auch mit Unbekannten vernetzen.","en":"That way you can also network with strangers.","ru":"Так можно налаживать связи и с незнакомыми людьми.","vi":"Bằng cách này bạn cũng có thể kết nối với người lạ.","fa":"به این ترتیب می توانید با افراد غریبه نیز ارتباط برقرار کنید."},{"de":"Auf der Konferenz hatte ich die Gelegenheit, mich mit vielen Experten zu vernetzen.","en":"At the conference I had the chance to network with many experts.","ru":"На конференции у меня была возможность установить контакты со многими экспертами.","vi":"Tại hội nghị tôi có cơ hội kết nối với nhiều chuyên gia.","fa":"در کنفرانس من این فرصت را داشتم که با بسیاری از متخصصان ارتباط برقرار کنم."},{"de":"Über diese Plattform vernetzen sich Menschen mit ähnlichen Interessen.","en":"On this platform people with similar interests connect with one another.","ru":"На этой платформе люди со схожими интересами устанавливают связи друг с другом.","vi":"Những người có cùng sở thích kết nối thông qua nền tảng này.","fa":"افراد با علایق مشابه از طریق این پلت فرم ارتباط برقرار می کنند."}]},{"word":"sich verschlechtern","en":"to get worse; to deteriorate","ru":"ухудшаться","vi":"xấu đi","fa":"بدتر شدن","examples":[{"de":"Sein Gesundheitszustand hat sich verschlechtert.","en":"His state of health has deteriorated.","ru":"Его состояние здоровья ухудшилось.","vi":"Sức khỏe của anh ấy đã xấu đi.","fa":"وضعیت سلامتی او بدتر شده است."},{"de":"Wenn du nicht übst, verschlechtert sich dein Deutsch.","en":"If you don't practise, your German gets worse.","ru":"Если ты не будешь заниматься, твой немецкий ухудшится.","vi":"Nếu bạn không luyện tập, tiếng Đức của bạn sẽ kém đi.","fa":"اگر تمرین نکنید، آلمانی شما خراب می شود."}]},{"word":"sich verspäten","en":"to be late","ru":"опаздывать","vi":"đến muộn","fa":"دیر شود","examples":[{"de":"Der Zug hat sich um zehn Minuten verspätet.","en":"The train was ten minutes late.","ru":"Поезд опоздал на десять минут.","vi":"Tàu đã trễ mười phút.","fa":"قطار ده دقیقه تاخیر داشت."},{"de":"Entschuldigung, ich habe mich verspätet.","en":"Sorry, I was late.","ru":"Извините, я опоздал.","vi":"Xin lỗi, tôi đến muộn.","fa":"ببخشید دیر اومدم"},{"de":"Wenn du dich verspätest, ruf bitte an.","en":"If you are late, please call.","ru":"Если опаздываешь, позвони, пожалуйста.","vi":"Nếu bạn đến muộn, vui lòng gọi.","fa":"اگر دیر کردید لطفا تماس بگیرید."}]},{"word":"sich verstecken","en":"to hide (oneself)","ru":"прятаться","vi":"trốn","fa":"پنهان کردن","examples":[{"de":"Die Kinder haben sich im Garten versteckt.","en":"The children hid in the garden.","ru":"Дети спрятались в саду.","vi":"Bọn trẻ trốn trong vườn.","fa":"بچه ها در باغ پنهان شدند."},{"de":"Er versteckte sich hinter dem Vorhang.","en":"He hid behind the curtain.","ru":"Он спрятался за занавеской.","vi":"Anh trốn sau tấm rèm.","fa":"پشت پرده پنهان شد."}]},{"word":"sich verstehen","en":"to get along (with someone), to understand each other","ru":"ладить, понимать друг друга","vi":"hiểu nhau","fa":"یکدیگر را درک کنند","examples":[{"de":"Wir verstehen uns sehr gut mit unseren Nachbarn.","en":"We get along very well with our neighbors.","ru":"Мы очень хорошо ладим с нашими соседями.","vi":"Chúng tôi rất hòa thuận với hàng xóm của mình.","fa":"ما با همسایه هایمان خیلی خوب هستیم."},{"de":"Trotz der Sprachbarriere haben wir uns gut verstanden.","en":"Despite the language barrier, we understood each other well.","ru":"Несмотря на языковой барьер, мы хорошо понимали друг друга.","vi":"Bất chấp rào cản ngôn ngữ, chúng tôi rất hợp nhau.","fa":"با وجود مانع زبانی، با هم خوب بودیم."}]},{"word":"sich vorbereiten","en":"to prepare (oneself)","ru":"готовиться","vi":"chuẩn bị cho mình","fa":"خودت را آماده کن","examples":[{"de":"Ich bereite mich gerade auf die Prüfung vor.","en":"I'm currently preparing for the exam.","ru":"Я сейчас готовлюсь к экзамену.","vi":"Ich bereite mich gerade auf die Prüfung vor.","fa":"در حال حاضر برای امتحان آماده می شوم."},{"de":"Wir müssen uns gut auf das Gespräch vorbereiten.","en":"We need to prepare well for the interview.","ru":"Нам нужно хорошо подготовиться к беседе.","vi":"Chúng ta phải chuẩn bị tốt cho cuộc phỏng vấn.","fa":"باید برای مصاحبه خوب آماده شویم."}]},{"word":"sich vorstellen","en":"to imagine; to introduce oneself","ru":"представлять себе; представляться","vi":"tưởng tượng","fa":"تصور کنید","examples":[{"de":"Ich kann mir nicht vorstellen, wie das funktionieren soll.","en":"I can't imagine how that's supposed to work.","ru":"Я не могу представить, как это должно работать.","vi":"Tôi không thể tưởng tượng được nó sẽ hoạt động như thế nào.","fa":"من نمی توانم تصور کنم که چگونه این قرار است کار کند."},{"de":"Darf ich mich kurz vorstellen? Ich heiße Anna.","en":"May I briefly introduce myself? My name is Anna.","ru":"Позвольте представиться. Меня зовут Анна.","vi":"Tôi có thể giới thiệu ngắn gọn về bản thân được không? Tên tôi là Anna.","fa":"ممکن است به طور خلاصه خودم را معرفی کنم؟ اسم من آنا است."}]},{"word":"sich waschen","en":"to wash oneself","ru":"мыться","vi":"rửa mình","fa":"خود را بشویید","examples":[{"de":"Ich wasche mich jeden Morgen kalt.","en":"I wash myself with cold water every morning.","ru":"Я умываюсь холодной водой каждое утро.","vi":"Tôi giặt nước lạnh vào mỗi buổi sáng.","fa":"من هر روز صبح سرد می شوم."},{"de":"Die Kinder waschen sich vor dem Essen die Hände.","en":"The children wash their hands before eating.","ru":"Дети моют руки перед едой.","vi":"Trẻ rửa tay trước khi ăn.","fa":"بچه ها قبل از غذا دست های خود را می شویند."}]},{"word":"sich weigern","en":"to refuse","ru":"отказываться","vi":"refuse","fa":"رد کردن","examples":[{"de":"Er weigert sich, die Regeln zu akzeptieren.","en":"He refuses to accept the rules.","ru":"Он отказывается принимать правила.","vi":"Anh ta từ chối chấp nhận các quy tắc.","fa":"او از پذیرش قوانین خودداری می کند."},{"de":"Sie weigerte sich, die Tür zu öffnen.","en":"She refused to open the door.","ru":"Она отказалась открыть дверь.","vi":"Cô từ chối mở cửa.","fa":"او حاضر نشد در را باز کند."}]},{"word":"sich wundern","en":"to be surprised","ru":"удивляться","vi":"ngạc nhiên","fa":"تعجب","examples":[{"de":"Ich wundere mich über sein Verhalten.","en":"I'm surprised by his behavior.","ru":"Я удивляюсь его поведению.","vi":"Tôi ngạc nhiên trước hành vi của anh ấy.","fa":"من از رفتار او تعجب می کنم."},{"de":"Wir wunderten uns, dass niemand da war.","en":"We were surprised that no one was there.","ru":"Мы удивились, что там никого не было.","vi":"Chúng tôi rất ngạc nhiên khi không có ai ở đó.","fa":"ما تعجب کردیم که کسی آنجا نبود."}]},{"word":"sich wünschen","en":"to wish for","ru":"желать себе, хотеть","vi":"ước gì","fa":"آرزو کن","examples":[{"de":"Ich wünsche mir einen ruhigen Urlaub.","en":"I wish for a relaxing vacation.","ru":"Я хочу спокойный отпуск.","vi":"Tôi chúc bạn một kỳ nghỉ yên bình.","fa":"برای شما تعطیلات آرامی آرزو می کنم."},{"de":"Was wünschst du dir zu Weihnachten?","en":"What do you wish for for Christmas?","ru":"Что ты хочешь на Рождество?","vi":"Bạn muốn gì cho Giáng sinh?","fa":"برای کریسمس چه می خواهید؟"}]},{"word":"sich zwingen","en":"to force oneself","ru":"заставлять себя","vi":"ép buộc bản thân","fa":"خودت را مجبور کن","examples":[{"de":"Ich musste mich zwingen, früh aufzustehen.","en":"I had to force myself to get up early.","ru":"Мне пришлось заставить себя рано встать.","vi":"Tôi buộc mình phải dậy sớm.","fa":"مجبور شدم به زور خودم را زود بیدار کنم."},{"de":"Er zwingt sich jeden Tag zum Sport.","en":"He forces himself to exercise every day.","ru":"Он каждый день заставляет себя заниматься спортом.","vi":"Anh buộc mình phải tập thể dục mỗi ngày.","fa":"او خود را مجبور می کند که هر روز ورزش کند."}]},{"word":"sicher","en":"safe; certain","ru":"безопасный; уверенный","vi":"chắc chắn rồi","fa":"مطمئن","examples":[{"de":"Bist du sicher, dass das der richtige Weg ist?","en":"Are you sure that this is the right way?","ru":"Ты уверен, что это правильная дорога?","vi":"Bạn có chắc chắn đây là cách đúng đắn?","fa":"مطمئنی این راه درسته؟"},{"de":"In diesem Viertel fühlen sich die Menschen sicher.","en":"People feel safe in this neighborhood.","ru":"В этом районе люди чувствуют себя в безопасности.","vi":"People feel safe in this neighborhood.","fa":"مردم در این محله احساس امنیت می کنند."}]},{"word":"die Sicherheit","en":"safety; security; certainty","ru":"безопасность; уверенность","vi":"an ninh","fa":"امنیت","examples":[{"de":"Die Sicherheit der Passagiere hat oberste Priorität.","en":"The safety of the passengers is the top priority.","ru":"Безопасность пассажиров — главный приоритет.","vi":"An toàn của hành khách là ưu tiên hàng đầu.","fa":"ایمنی مسافران در اولویت قرار دارد."},{"de":"Ich kann nicht mit Sicherheit sagen, ob er kommt.","en":"I can't say for certain whether he's coming.","ru":"Я не могу сказать с уверенностью, придёт ли он.","vi":"Tôi không thể nói chắc chắn liệu anh ấy có đến hay không.","fa":"نمی توانم با اطمینان بگویم که او می آید یا نه."}]},{"word":"sichern","en":"to secure; to save (data)","ru":"защищать; сохранять (данные)","vi":"an toàn","fa":"امن","examples":[{"de":"Vergiss nicht, deine Daten regelmäßig zu sichern.","en":"Don't forget to back up your data regularly.","ru":"Не забывай регулярно сохранять свои данные.","vi":"Đừng quên sao lưu dữ liệu của bạn thường xuyên.","fa":"فراموش نکنید که به طور منظم از اطلاعات خود نسخه پشتیبان تهیه کنید."},{"de":"Die Polizei sichert den Tatort.","en":"The police are securing the crime scene.","ru":"Полиция охраняет место преступления.","vi":"Cảnh sát bảo vệ hiện trường vụ án.","fa":"پلیس محل جنایت را ایمن می کند."}]},{"word":"die Sicherung","en":"backup","ru":"резервная копия, бэкап","vi":"bản sao lưu","fa":"پشتیبان گیری","examples":[{"de":"Mach regelmäßig eine Sicherung deiner wichtigen Dateien.","en":"Make a regular backup of your important files.","ru":"Регулярно делай резервную копию своих важных файлов.","vi":"Sao lưu các tập tin quan trọng của bạn thường xuyên.","fa":"به طور منظم از فایل های مهم خود نسخه پشتیبان تهیه کنید."},{"de":"Zum Glück hatte ich eine Sicherung von gestern.","en":"Luckily I had a backup from yesterday.","ru":"К счастью, у меня была резервная копия со вчерашнего дня.","vi":"May mắn thay tôi đã có một bản sao lưu từ ngày hôm qua.","fa":"خوشبختانه من یک نسخه پشتیبان از دیروز داشتم."},{"de":"Die Sicherung wird jede Nacht automatisch erstellt.","en":"The backup is created automatically every night.","ru":"Резервная копия создаётся автоматически каждую ночь.","vi":"Bản sao lưu được tạo tự động mỗi đêm.","fa":"پشتیبان گیری به طور خودکار هر شب ایجاد می شود."}]},{"word":"sichtbar","en":"visible","ru":"видимый","vi":"có thể nhìn thấy","fa":"قابل مشاهده است","examples":[{"de":"Von hier aus ist der Berg gut sichtbar.","en":"From here, the mountain is clearly visible.","ru":"Отсюда гора хорошо видна.","vi":"Từ đây có thể nhìn thấy rõ ngọn núi.","fa":"از اینجا کوه به وضوح قابل مشاهده است."},{"de":"Die Narbe ist kaum noch sichtbar.","en":"The scar is hardly visible anymore.","ru":"Шрам теперь едва заметен.","vi":"Vết sẹo hầu như không nhìn thấy được.","fa":"جای زخم به سختی قابل مشاهده است."}]},{"word":"der Sieg","en":"victory","ru":"победа","vi":"chiến thắng","fa":"پیروزی","examples":[{"de":"Der Sieg über das feindliche Heer wurde groß gefeiert.","en":"The victory over the enemy army was celebrated greatly.","ru":"Победу над вражеским войском широко праздновали.","vi":"Chiến thắng trước quân địch được ăn mừng rộng rãi.","fa":"پیروزی بر ارتش دشمن جشن گسترده ای برگزار شد."},{"de":"Nach dem Sieg gründete der General ein neues Reich.","en":"After the victory the general founded a new empire.","ru":"После победы генерал основал новую империю.","vi":"Sau chiến thắng, vị tướng này đã thành lập một đế chế mới.","fa":"پس از پیروزی، ژنرال امپراتوری جدیدی را تأسیس کرد."},{"de":"Der Sieg kam für viele völlig überraschend.","en":"The victory came as a complete surprise to many.","ru":"Победа для многих оказалась полной неожиданностью.","vi":"Chiến thắng đến hoàn toàn bất ngờ với nhiều người.","fa":"این پیروزی برای بسیاری غافلگیر کننده بود."}]},{"word":"siegen","en":"to win; to be victorious","ru":"побеждать","vi":"thắng","fa":"برنده شوید","examples":[{"de":"Unsere Mannschaft hat gestern klar gesiegt.","en":"Our team clearly won yesterday.","ru":"Наша команда вчера уверенно победила.","vi":"Đội của chúng tôi đã thắng rõ ràng ngày hôm qua.","fa":"تیم ما دیروز به وضوح پیروز شد."},{"de":"Wer wird bei diesem Wettbewerb siegen?","en":"Who will win this competition?","ru":"Кто победит в этом соревновании?","vi":"Ai sẽ giành chiến thắng trong cuộc thi này?","fa":"چه کسی برنده این رقابت خواهد شد؟"}]},{"word":"der Sieger","en":"winner (male)","ru":"победитель","vi":"người chiến thắng","fa":"برنده","examples":[{"de":"Der Sieger des Rennens bekam einen Pokal.","en":"The winner of the race received a trophy.","ru":"Победитель гонки получил кубок.","vi":"Người chiến thắng cuộc đua nhận được một chiếc cúp.","fa":"برنده مسابقه یک جایزه دریافت کرد."},{"de":"Am Ende stand der Sieger fest.","en":"In the end the winner was decided.","ru":"В конце определился победитель.","vi":"Cuối cùng người chiến thắng đã rõ ràng.","fa":"در نهایت برنده مشخص بود."},{"de":"Die Sieger wurden mit Applaus begrüßt.","en":"The winners were welcomed with applause.","ru":"Победителей встретили аплодисментами.","vi":"Những người chiến thắng được chào đón bằng những tràng pháo tay.","fa":"از برندگان با تشویق استقبال شد."}]},{"word":"die Siegerin","en":"winner (female)","ru":"победительница","vi":"người chiến thắng","fa":"برنده","examples":[{"de":"Die Siegerin lächelte glücklich in die Kamera.","en":"The winner smiled happily into the camera.","ru":"Победительница радостно улыбнулась в камеру.","vi":"Người chiến thắng mỉm cười hạnh phúc trước ống kính.","fa":"برنده با خوشحالی به دوربین لبخند زد."},{"de":"Die Siegerin des Wettbewerbs ist erst zwölf Jahre alt.","en":"The winner of the competition is only twelve years old.","ru":"Победительнице конкурса всего двенадцать лет.","vi":"Người chiến thắng trong cuộc thi chỉ mới mười hai tuổi.","fa":"برنده مسابقه فقط دوازده سال سن دارد."},{"de":"Alle gratulierten der Siegerin herzlich.","en":"Everyone warmly congratulated the winner.","ru":"Все сердечно поздравили победительницу.","vi":"Mọi người nhiệt liệt chúc mừng người chiến thắng.","fa":"همه به گرمی به برنده تبریک گفتند."}]},{"word":"siezen","en":"to address someone formally (with 'Sie')","ru":"обращаться к кому-либо на «вы» (на «Sie»)","vi":"siezen","fa":"سیزن","examples":[{"de":"In der Firma siezen sich die meisten Kollegen.","en":"At the company most colleagues address each other formally.","ru":"В компании большинство коллег обращаются друг к другу на «вы».","vi":"Hầu hết đồng nghiệp trong công ty đều ngồi cùng nhau.","fa":"اکثر همکاران در شرکت دور هم می نشینند."},{"de":"Soll ich Sie weiterhin siezen oder dürfen wir uns duzen?","en":"Should I keep addressing you formally, or may we use first names?","ru":"Мне продолжать обращаться к вам на «вы» или перейдём на «ты»?","vi":"Tôi có nên tiếp tục gọi cho bạn hay chúng ta có thể gọi bằng tên riêng?","fa":"آیا باید همچنان با شما تماس بگیرم یا می‌توانیم با شرایط نام خانوادگی صحبت کنیم؟"},{"de":"Ältere Menschen erwartet man oft zu siezen.","en":"You are often expected to address older people formally.","ru":"К пожилым людям часто принято обращаться на «вы».","vi":"Người già thường được cho là sẽ chết.","fa":"اغلب انتظار می رود افراد مسن بمیرند."}]},{"word":"singen","en":"to sing","ru":"петь","vi":"hát","fa":"آواز خواندن","examples":[{"de":"Meine Tochter singt sehr gern im Chor.","en":"My daughter really likes to sing in the choir.","ru":"Моя дочь очень любит петь в хоре.","vi":"Con gái tôi thực sự thích hát trong dàn hợp xướng.","fa":"دخترم از خواندن در گروه کر بسیار لذت می برد."},{"de":"Er singt jeden Abend seinem Baby ein Lied vor.","en":"He sings his baby a song every evening.","ru":"Он каждый вечер поёт своему малышу песню.","vi":"Anh ấy hát một bài hát cho con mình nghe vào mỗi buổi tối.","fa":"او هر روز غروب برای نوزادش آهنگی می خواند."}]},{"word":"sinken","en":"to sink; to decrease","ru":"тонуть; снижаться","vi":"bồn rửa","fa":"فرو رفتن؛ کاهش یافتن","examples":[{"de":"Die Preise für Energie sind im letzten Monat gesunken.","en":"Energy prices have decreased over the last month.","ru":"Цены на энергию снизились за последний месяц.","vi":"Giá năng lượng đã giảm trong tháng qua.","fa":"قیمت انرژی در ماه گذشته کاهش یافته است."},{"de":"Das Schiff begann langsam zu sinken.","en":"The ship began to sink slowly.","ru":"Корабль начал медленно тонуть.","vi":"Con tàu bắt đầu chìm dần.","fa":"کشتی کم کم شروع به غرق شدن کرد."}]},{"word":"der Sinn","en":"sense; meaning","ru":"смысл; чувство","vi":"ý nghĩa","fa":"معنی","examples":[{"de":"Diese Regel ergibt für mich keinen Sinn.","en":"This rule doesn't make sense to me.","ru":"Это правило не имеет для меня смысла.","vi":"Quy tắc này không có ý nghĩa với tôi.","fa":"این قانون برای من معنی ندارد."},{"de":"Der Geruchssinn ist bei Hunden sehr gut entwickelt.","en":"The sense of smell is very well developed in dogs.","ru":"Обоняние у собак очень хорошо развито.","vi":"Khứu giác ở chó rất phát triển.","fa":"حس بویایی در سگ ها بسیار توسعه یافته است."}]},{"word":"sinnlos","en":"pointless, meaningless","ru":"бессмысленный, бесполезный","vi":"vô nghĩa","fa":"بی معنی","examples":[{"de":"Es ist sinnlos, jetzt noch zu streiten.","en":"It's pointless to keep arguing now.","ru":"Бессмысленно продолжать спор сейчас.","vi":"Bây giờ tranh cãi cũng vô nghĩa.","fa":"الان بحث بیهوده است"},{"de":"Ohne Plan war die ganze Reise sinnlos.","en":"Without a plan the whole trip was pointless.","ru":"Без плана вся поездка была бессмысленной.","vi":"Không có kế hoạch, toàn bộ chuyến đi là vô nghĩa.","fa":"بدون برنامه، کل سفر بی معنی بود."},{"de":"Ich finde solche Diskussionen völlig sinnlos.","en":"I find such discussions completely pointless.","ru":"Я считаю такие дискуссии совершенно бессмысленными.","vi":"Tôi thấy những cuộc thảo luận như vậy hoàn toàn vô nghĩa.","fa":"من چنین بحث هایی را کاملا بیهوده می دانم."}]},{"word":"sinnvoll","en":"sensible, meaningful, useful","ru":"разумный, осмысленный, целесообразный","vi":"có ý nghĩa","fa":"معنا پیدا می کند","examples":[{"de":"Es ist sinnvoll, früh mit dem Lernen anzufangen.","en":"It is sensible to start learning early.","ru":"Разумно начинать учиться рано.","vi":"Việc bắt đầu học sớm là điều hợp lý.","fa":"شروع یادگیری زود هنگام منطقی است."},{"de":"Wir suchen eine sinnvolle Lösung für das Problem.","en":"We are looking for a sensible solution to the problem.","ru":"Мы ищем разумное решение проблемы.","vi":"Chúng tôi đang tìm kiếm một giải pháp hợp lý cho vấn đề.","fa":"ما به دنبال یک راه حل معقول برای مشکل هستیم."},{"de":"Findest du es sinnvoll, ein Auto zu kaufen?","en":"Do you think it makes sense to buy a car?","ru":"Ты считаешь, что покупать машину имеет смысл?","vi":"Bạn có nghĩ việc mua một chiếc ô tô là hợp lý không?","fa":"به نظر شما خرید ماشین منطقی است؟"}]},{"word":"die Situation","en":"situation","ru":"ситуация","vi":"tình hình","fa":"وضعیت","examples":[{"de":"Die wirtschaftliche Situation hat sich in den letzten Jahren verbessert.","en":"The economic situation has improved in recent years.","ru":"Экономическая ситуация улучшилась за последние годы.","vi":"Tình hình kinh tế đã được cải thiện trong những năm gần đây.","fa":"وضعیت اقتصادی در سال های اخیر بهبود یافته است."},{"de":"In dieser schwierigen Situation brauchen wir Ihre Hilfe.","en":"In this difficult situation, we need your help.","ru":"В этой сложной ситуации нам нужна ваша помощь.","vi":"Trong tình huống khó khăn này, chúng tôi cần sự giúp đỡ của bạn.","fa":"در این شرایط سخت نیازمند کمک شما هستیم."}]},{"word":"der Sitz","en":"seat","ru":"сиденье; место (в парламенте); местонахождение (фирмы)","vi":"chỗ ngồi","fa":"صندلی","examples":[{"de":"Bitte stellen Sie Ihren Sitz aufrecht.","en":"Please put your seat upright.","ru":"Пожалуйста, приведите спинку сиденья в вертикальное положение.","vi":"Xin vui lòng đặt chỗ ngồi của bạn thẳng đứng.","fa":"لطفا صندلی خود را صاف قرار دهید."},{"de":"Der Sitz im Zug war sehr bequem.","en":"The seat on the train was very comfortable.","ru":"Сиденье в поезде было очень удобным.","vi":"Chỗ ngồi trên tàu rất thoải mái.","fa":"صندلی در قطار بسیار راحت بود."},{"de":"Die Firma hat ihren Sitz in München.","en":"The company has its headquarters in Munich.","ru":"Головной офис компании находится в Мюнхене.","vi":"Công ty có trụ sở tại München.","fa":"این شرکت در مونیخ مستقر است."}]},{"word":"sitzen","en":"to sit","ru":"сидеть","vi":"ngồi","fa":"بنشین","examples":[{"de":"Er sitzt den ganzen Tag am Computer.","en":"He sits at the computer all day.","ru":"Он весь день сидит за компьютером.","vi":"Anh ấy ngồi trước máy tính cả ngày.","fa":"تمام روز پشت کامپیوتر می نشیند."},{"de":"Wir haben lange auf der Bank im Park gesessen.","en":"We sat on the bench in the park for a long time.","ru":"Мы долго сидели на скамейке в парке.","vi":"Chúng tôi ngồi trên băng ghế trong công viên một lúc lâu.","fa":"مدت زیادی روی نیمکت پارک نشستیم."}]},{"word":"der Ski","en":"ski","ru":"лыжа","vi":"ván trượt","fa":"اسکی ها","examples":[{"de":"Im Winter fahre ich gern Ski.","en":"In winter I like to ski.","ru":"Зимой я люблю кататься на лыжах.","vi":"Tôi thích trượt tuyết vào mùa đông.","fa":"در زمستان اسکی را دوست دارم."},{"de":"Er hat sich neue Ski gekauft.","en":"He bought himself new skis.","ru":"Он купил себе новые лыжи.","vi":"Anh ấy đã mua ván trượt mới.","fa":"اسکی نو خرید."},{"de":"Meine Ski sind zu kurz für mich.","en":"My skis are too short for me.","ru":"Мои лыжи для меня слишком короткие.","vi":"Ván trượt của tôi quá ngắn đối với tôi.","fa":"اسکی من برای من خیلی کوتاه است."}]},{"word":"der Ski/Schi","en":"ski","ru":"лыжа","vi":"trượt tuyết/trượt tuyết","fa":"اسکی/اسکی","examples":[{"de":"Im Winter fahren wir jedes Jahr Ski in den Alpen.","en":"In winter, we go skiing in the Alps every year.","ru":"Зимой мы каждый год катаемся на лыжах в Альпах.","vi":"Chúng tôi trượt tuyết trên dãy Alps hàng năm vào mùa đông.","fa":"ما هر سال در زمستان در کوه های آلپ اسکی می کنیم."},{"de":"Er hat sich neue Skier für die Saison gekauft.","en":"He bought new skis for the season.","ru":"Он купил новые лыжи для сезона.","vi":"Anh ấy đã mua ván trượt mới cho mùa giải.","fa":"او برای فصل اسکی جدید خرید."}]},{"word":"der Skiurlaub","en":"skiing holiday","ru":"лыжный отпуск, отдых на горнолыжном курорте","vi":"kỳ nghỉ trượt tuyết","fa":"تعطیلات اسکی","examples":[{"de":"Wir machen jedes Jahr Skiurlaub in den Alpen.","en":"We go on a skiing holiday in the Alps every year.","ru":"Каждый год мы ездим кататься на лыжах в Альпы.","vi":"Chúng tôi đi nghỉ trượt tuyết ở dãy Alps hàng năm.","fa":"ما هر سال به تعطیلات اسکی در کوه های آلپ می رویم."},{"de":"Der Skiurlaub war leider sehr teuer.","en":"The skiing holiday was unfortunately very expensive.","ru":"Лыжный отпуск, к сожалению, был очень дорогим.","vi":"Thật không may, kỳ nghỉ trượt tuyết rất tốn kém.","fa":"متأسفانه تعطیلات اسکی بسیار گران بود."},{"de":"Im Skiurlaub hat es viel geschneit.","en":"It snowed a lot during the skiing holiday.","ru":"Во время лыжного отпуска выпало много снега.","vi":"Tuyết rơi rất nhiều vào kỳ nghỉ trượt tuyết của chúng tôi.","fa":"در تعطیلات اسکی ما برف زیادی بارید."}]},{"word":"der Smog","en":"smog","ru":"смог","vi":"sương khói","fa":"مه دود","examples":[{"de":"Über der Großstadt liegt dichter Smog.","en":"Thick smog hangs over the big city.","ru":"Над большим городом висит густой смог.","vi":"Có sương mù dày đặc trên thành phố.","fa":"دود غلیظی در سطح شهر وجود دارد."},{"de":"Der Smog macht vielen Menschen das Atmen schwer.","en":"The smog makes it hard for many people to breathe.","ru":"Смог многим людям затрудняет дыхание.","vi":"Khói bụi khiến nhiều người khó thở.","fa":"مه دود نفس کشیدن را برای بسیاری از افراد دشوار می کند."},{"de":"An Tagen mit starkem Smog bleiben die Schulen geschlossen.","en":"On days with heavy smog the schools stay closed.","ru":"В дни с сильным смогом школы остаются закрытыми.","vi":"Các trường học vẫn đóng cửa vào những ngày có sương mù dày đặc.","fa":"مدارس در روزهایی که مه دود شدید بسته است."}]},{"word":"der Snack","en":"snack","ru":"перекус, лёгкая закуска","vi":"bữa ăn nhẹ","fa":"میان وعده","examples":[{"de":"Zwischen den Mahlzeiten esse ich manchmal einen Snack.","en":"Between meals I sometimes eat a snack.","ru":"Между приёмами пищи я иногда ем перекус.","vi":"Đôi khi tôi ăn một bữa ăn nhẹ giữa các bữa ăn.","fa":"من گاهی بین وعده های غذایی میان وعده می خورم."},{"de":"Ein gesunder Snack ist zum Beispiel Obst.","en":"A healthy snack is fruit, for example.","ru":"Здоровый перекус — это, например, фрукты.","vi":"Ví dụ, một bữa ăn nhẹ lành mạnh là trái cây.","fa":"یک میان وعده سالم به عنوان مثال میوه است."},{"de":"Am Bahnhof kaufte ich mir schnell einen Snack.","en":"At the station I quickly bought myself a snack.","ru":"На вокзале я быстро купил себе перекус.","vi":"Tôi nhanh chóng mua đồ ăn nhẹ ở ga xe lửa.","fa":"سریع از ایستگاه قطار یک میان وعده خریدم."}]},{"word":"so","en":"so; like this","ru":"так; таким образом","vi":"như thế","fa":"مانند آن","examples":[{"de":"Mach es bitte genau so, wie ich es dir gezeigt habe.","en":"Please do it exactly like this, as I showed you.","ru":"Пожалуйста, сделай это именно так, как я тебе показал.","vi":"Hãy làm chính xác như tôi đã chỉ cho bạn.","fa":"لطفا این کار را دقیقا همانطور که به شما نشان دادم انجام دهید."},{"de":"Sie war so müde, dass sie sofort einschlief.","en":"She was so tired that she fell asleep immediately.","ru":"Она была так устала, что сразу же уснула.","vi":"Cô mệt đến nỗi ngủ ngay lập tức.","fa":"آنقدر خسته بود که بلافاصله خوابش برد."}]},{"word":"so dass","en":"so that, with the result that","ru":"так что, вследствие чего","vi":"vậy đó","fa":"به طوری که","examples":[{"de":"Es regnete stark, so dass wir zu Hause blieben.","en":"It was raining hard, so that we stayed at home.","ru":"Шёл сильный дождь, так что мы остались дома.","vi":"Trời mưa to nên chúng tôi ở nhà.","fa":"باران شدیدی می بارید و ما در خانه ماندیم."},{"de":"Sie sprach langsam, so dass alle sie verstanden.","en":"She spoke slowly, so that everyone understood her.","ru":"Она говорила медленно, так что все её понимали.","vi":"Cô nói chậm để mọi người có thể hiểu được.","fa":"آهسته صحبت کرد تا همه او را بفهمند."},{"de":"Der Zug hatte Verspätung, so dass ich den Anschluss verpasste.","en":"The train was late, so that I missed the connection.","ru":"Поезд опоздал, так что я пропустил пересадку.","vi":"Tàu bị trễ nên tôi bị lỡ chuyến.","fa":"قطار دیر آمد، بنابراین من اتصال را از دست دادم."}]},{"word":"so genannt","en":"so-called","ru":"так называемый","vi":"cái gọi là","fa":"به اصطلاح","examples":[{"de":"Die so genannten Experten lagen völlig falsch.","en":"The so-called experts were completely wrong.","ru":"Так называемые эксперты полностью ошиблись.","vi":"Những người được gọi là chuyên gia đã hoàn toàn sai lầm.","fa":"به اصطلاح کارشناسان کاملا در اشتباه بودند."},{"de":"Wir besuchten das so genannte alte Viertel.","en":"We visited the so-called old quarter.","ru":"Мы посетили так называемый старый квартал.","vi":"Chúng tôi đã đến thăm cái gọi là khu phố cổ.","fa":"از محله به اصطلاح قدیمی بازدید کردیم."},{"de":"Sein so genannter Freund half ihm nie.","en":"His so-called friend never helped him.","ru":"Его так называемый друг никогда ему не помогал.","vi":"Người được gọi là bạn của anh ấy chưa bao giờ giúp đỡ anh ấy.","fa":"به اصطلاح دوستش هرگز به او کمک نکرد."}]},{"word":"so viel/so viel wie","en":"as much (as)","ru":"столько (же), сколько","vi":"nhiều/nhiều như","fa":"به اندازه/به اندازه","examples":[{"de":"Er verdient nicht so viel wie sein Bruder.","en":"He doesn't earn as much as his brother.","ru":"Он зарабатывает не столько, сколько его брат.","vi":"Anh ấy không kiếm được nhiều tiền như anh trai mình.","fa":"او به اندازه برادرش درآمد ندارد."},{"de":"Iss so viel du willst.","en":"Eat as much as you want.","ru":"Ешь столько, сколько хочешь.","vi":"Ăn nhiều như bạn muốn.","fa":"هرچقدر میخوای بخور"}]},{"word":"die Soap","en":"soap opera","ru":"мыльная опера (сериал)","vi":"xà phòng","fa":"صابون","examples":[{"de":"Meine Mutter schaut jeden Tag ihre Lieblings-Soap.","en":"My mother watches her favourite soap every day.","ru":"Моя мама каждый день смотрит свою любимую мыльную оперу.","vi":"Mẹ tôi xem bộ phim yêu thích của bà mỗi ngày.","fa":"مادرم هر روز صابون مورد علاقه اش را تماشا می کند."},{"de":"Diese Soap läuft schon seit über zwanzig Jahren.","en":"This soap has been running for over twenty years.","ru":"Эта мыльная опера идёт уже больше двадцати лет.","vi":"Xà phòng này đã hoạt động được hơn hai mươi năm.","fa":"این صابون بیش از بیست سال است که کار می کند."},{"de":"In der Soap gibt es immer viel Drama.","en":"In the soap there is always a lot of drama.","ru":"В мыльной опере всегда много драмы.","vi":"Luôn có rất nhiều kịch tính trong bộ phim.","fa":"همیشه درام زیادی در صابون وجود دارد."}]},{"word":"sobald","en":"as soon as","ru":"как только","vi":"ngay khi","fa":"به محض","examples":[{"de":"Ich rufe dich an, sobald ich zu Hause bin.","en":"I will call you as soon as I get home.","ru":"Я позвоню тебе, как только буду дома.","vi":"Tôi sẽ gọi cho bạn ngay khi tôi về đến nhà.","fa":"به محض اینکه رسیدم خونه بهت زنگ میزنم"},{"de":"Sobald es regnet, machen wir die Fenster zu.","en":"As soon as it rains, we close the windows.","ru":"Как только начинается дождь, мы закрываем окна.","vi":"Ngay khi trời mưa, chúng tôi đóng cửa sổ lại.","fa":"به محض اینکه باران می بارد، پنجره ها را می بندیم."}]},{"word":"die Socke","en":"sock","ru":"носок","vi":"chiếc tất","fa":"جوراب","examples":[{"de":"Ich habe im Trockner nur eine Socke gefunden.","en":"I only found one sock in the dryer.","ru":"Я нашёл в сушилке только один носок.","vi":"Tôi chỉ tìm thấy một chiếc tất trong máy sấy.","fa":"من فقط یک جوراب در خشک کن پیدا کردم."},{"de":"Im Winter trage ich immer warme Socken.","en":"In winter, I always wear warm socks.","ru":"Зимой я всегда ношу тёплые носки.","vi":"Vào mùa đông tôi luôn mang tất ấm.","fa":"در زمستان همیشه جوراب گرم می پوشم."}]},{"word":"sodass","en":"so that","ru":"так что","vi":"vậy đó","fa":"به طوری که","examples":[{"de":"Es regnete stark, sodass wir zu Hause bleiben mussten.","en":"It rained heavily, so that we had to stay home.","ru":"Шёл сильный дождь, так что нам пришлось остаться дома.","vi":"Trời mưa to nên chúng tôi phải ở nhà.","fa":"باران شدیدی می بارید و مجبور شدیم در خانه بمانیم."},{"de":"Er lernte fleißig, sodass er die Prüfung bestand.","en":"He studied diligently, so that he passed the exam.","ru":"Он усердно учился, так что сдал экзамен.","vi":"Anh ấy học tập chăm chỉ nên anh ấy đã vượt qua kỳ thi.","fa":"به سختی درس خواند تا در امتحان قبول شد."}]},{"word":"das Sofa","en":"sofa","ru":"диван","vi":"ghế sofa","fa":"مبل","examples":[{"de":"Nach der Arbeit legt er sich gern aufs Sofa.","en":"After work, he likes to lie down on the sofa.","ru":"После работы он любит прилечь на диван.","vi":"Sau giờ làm việc anh ấy thích nằm dài trên ghế sofa.","fa":"بعد از کار دوست دارد روی مبل دراز بکشد."},{"de":"Wir haben ein neues Sofa fürs Wohnzimmer gekauft.","en":"We bought a new sofa for the living room.","ru":"Мы купили новый диван для гостиной.","vi":"Chúng tôi đã mua một chiếc ghế sofa mới cho phòng khách.","fa":"یک مبل جدید برای اتاق نشیمن خریدیم."}]},{"word":"sofort","en":"immediately","ru":"немедленно","vi":"ngay lập tức","fa":"بلافاصله","examples":[{"de":"Ruf mich bitte sofort an, wenn du ankommst.","en":"Please call me immediately when you arrive.","ru":"Пожалуйста, позвони мне сразу, как только приедешь.","vi":"Hãy gọi cho tôi ngay khi bạn đến.","fa":"لطفاً وقتی رسیدید فوراً با من تماس بگیرید."},{"de":"Der Arzt kam sofort, als er von dem Unfall hörte.","en":"The doctor came immediately when he heard about the accident.","ru":"Врач пришёл немедленно, как только узнал об аварии.","vi":"Bác sĩ đến ngay lập tức khi nghe tin về vụ tai nạn.","fa":"دکتر با شنیدن خبر تصادف بلافاصله آمد."}]},{"word":"die Software","en":"software","ru":"программное обеспечение, софт","vi":"phần mềm","fa":"نرم افزار","examples":[{"de":"Die neue Software läuft auf allen Geräten im Büro.","en":"The new software runs on all the devices in the office.","ru":"Новое программное обеспечение работает на всех устройствах в офисе.","vi":"Phần mềm mới chạy trên tất cả các thiết bị trong văn phòng.","fa":"نرم افزار جدید بر روی تمام دستگاه های موجود در دفتر اجرا می شود."},{"de":"Die Software muss regelmäßig aktualisiert werden.","en":"The software has to be updated regularly.","ru":"Программное обеспечение нужно регулярно обновлять.","vi":"Phần mềm cần được cập nhật thường xuyên.","fa":"نرم افزار باید به طور مرتب به روز شود."},{"de":"Für diese Aufgabe brauchst du eine spezielle Software.","en":"For this task you need special software.","ru":"Для этой задачи тебе нужно специальное программное обеспечение.","vi":"Đối với nhiệm vụ này, bạn cần phần mềm đặc biệt.","fa":"برای این کار به نرم افزار خاصی نیاز دارید."}]},{"word":"sogar","en":"even","ru":"даже","vi":"thậm chí","fa":"حتی","examples":[{"de":"Er hat sogar am Sonntag gearbeitet.","en":"He even worked on Sunday.","ru":"Он даже работал в воскресенье.","vi":"Anh ấy thậm chí còn làm việc cả ngày chủ nhật.","fa":"حتی یکشنبه ها هم کار می کرد."},{"de":"Sogar meine kleine Schwester kann schon schwimmen.","en":"Even my little sister can already swim.","ru":"Даже моя младшая сестра уже умеет плавать.","vi":"Ngay cả em gái tôi bây giờ cũng có thể bơi được.","fa":"حتی خواهر کوچکم هم اکنون می تواند شنا کند."}]},{"word":"sogenannt","en":"so-called","ru":"так называемый","vi":"cái gọi là","fa":"به اصطلاح","examples":[{"de":"Der sogenannte Fortschritt brachte viele Probleme.","en":"The so-called progress brought many problems.","ru":"Так называемый прогресс принёс много проблем.","vi":"Cái gọi là tiến bộ mang lại nhiều vấn đề.","fa":"به اصطلاح پیشرفت مشکلات زیادی را به همراه داشت."},{"de":"Sie ist eine sogenannte Influencerin.","en":"She is a so-called influencer.","ru":"Она так называемый инфлюенсер.","vi":"Cô ấy được gọi là người có ảnh hưởng.","fa":"او به اصطلاح اینفلوئنسر است."},{"de":"Diese sogenannte Diät funktioniert nicht.","en":"This so-called diet doesn't work.","ru":"Эта так называемая диета не работает.","vi":"Cái gọi là chế độ ăn kiêng này không có tác dụng.","fa":"این رژیم به اصطلاح کار نمی کند."}]},{"word":"sogenannt-","en":"so-called","ru":"так называемый","vi":"cái gọi là-","fa":"به اصطلاح","examples":[{"de":"Er wohnt in einem sogenannten Passivhaus.","en":"He lives in a so-called passive house.","ru":"Он живёт в так называемом пассивном доме.","vi":"Anh ta sống trong một ngôi nhà được gọi là thụ động.","fa":"او در یک خانه به اصطلاح منفعل زندگی می کند."},{"de":"Die sogenannten Experten hatten alle eine andere Meinung.","en":"The so-called experts all had a different opinion.","ru":"У так называемых экспертов у всех было разное мнение.","vi":"Những người được gọi là chuyên gia đều có ý kiến ​​​​khác nhau.","fa":"به اصطلاح کارشناسان همه نظر متفاوتی داشتند."}]},{"word":"der Sohn","en":"son","ru":"сын","vi":"con trai","fa":"پسر","examples":[{"de":"Unser Sohn geht seit diesem Jahr in die Schule.","en":"Our son has been going to school since this year.","ru":"Наш сын с этого года ходит в школу.","vi":"Con trai chúng tôi đã đi học năm nay.","fa":"پسر ما امسال به مدرسه می رود."},{"de":"Sie hat zwei Söhne und eine Tochter.","en":"She has two sons and one daughter.","ru":"У неё два сына и одна дочь.","vi":"Cô có hai con trai và một con gái.","fa":"او دو پسر و یک دختر دارد."}]},{"word":"solange","en":"as long as","ru":"пока; до тех пор пока","vi":"miễn là","fa":"تا زمانی که","examples":[{"de":"Du darfst hier bleiben, solange du willst.","en":"You can stay here as long as you want.","ru":"Ты можешь оставаться здесь, пока хочешь.","vi":"Bạn có thể ở đây bao lâu tùy thích.","fa":"شما می توانید تا زمانی که بخواهید اینجا بمانید."},{"de":"Solange es regnet, spielen wir drinnen.","en":"As long as it rains, we play indoors.","ru":"Пока идёт дождь, мы играем в помещении.","vi":"Chỉ cần trời mưa là chúng tôi chơi trong nhà.","fa":"تا زمانی که باران می بارد، ما در داخل خانه بازی می کنیم."}]},{"word":"solch","en":"such, such a","ru":"такой, подобный","vi":"như vậy","fa":"چنین","examples":[{"de":"Eine solche Gelegenheit kommt selten.","en":"Such an opportunity rarely comes along.","ru":"Такая возможность выпадает редко.","vi":"Cơ hội như vậy hiếm khi đến.","fa":"چنین فرصتی به ندرت پیش می آید."},{"de":"Solch ein Verhalten kann ich nicht akzeptieren.","en":"I cannot accept such behaviour.","ru":"Я не могу принять такое поведение.","vi":"Tôi không thể chấp nhận hành vi như vậy.","fa":"من نمی توانم چنین رفتاری را بپذیرم."},{"de":"Mit solchen Problemen kenne ich mich nicht aus.","en":"I'm not familiar with such problems.","ru":"С такими проблемами я не знаком.","vi":"Tôi không quen với những vấn đề như vậy.","fa":"من با چنین مشکلاتی آشنا نیستم."}]},{"word":"solch-","en":"such","ru":"такой","vi":"như vậy-","fa":"چنین -","examples":[{"de":"Ich habe noch nie ein solches Chaos gesehen.","en":"I have never seen such chaos before.","ru":"Я никогда не видел такого хаоса.","vi":"Tôi chưa bao giờ thấy sự hỗn loạn như vậy.","fa":"من هرگز چنین هرج و مرج را ندیده بودم."},{"de":"Mit solchen Problemen hatten wir nicht gerechnet.","en":"We hadn't expected such problems.","ru":"Мы не ожидали таких проблем.","vi":"Chúng tôi không mong đợi những vấn đề như vậy.","fa":"ما انتظار چنین مشکلاتی را نداشتیم."}]},{"word":"sollen","en":"should; to be supposed to","ru":"должен (следует)","vi":"nên","fa":"باید","examples":[{"de":"Du sollst nicht so viel Zucker essen.","en":"You shouldn't eat so much sugar.","ru":"Тебе не следует есть так много сахара.","vi":"Bạn không nên ăn quá nhiều đường.","fa":"اینقدر شکر نباید بخوری"},{"de":"Was soll ich tun, wenn er nicht anruft?","en":"What should I do if he doesn't call?","ru":"Что мне делать, если он не позвонит?","vi":"Tôi nên làm gì nếu anh ấy không gọi?","fa":"اگه زنگ نزنه چیکار کنم؟"}]},{"word":"Sollen wir vielleicht …?","en":"Should we maybe …? (tentative suggestion)","ru":"Может, нам …? (осторожное предложение)","vi":"Có lẽ chúng ta có nên…?","fa":"شاید باید…؟","examples":[{"de":"Sollen wir vielleicht ein Taxi nehmen?","en":"Should we maybe take a taxi?","ru":"Может, нам взять такси?","vi":"Chúng ta có nên đi taxi không?","fa":"شاید باید تاکسی بگیریم؟"}]},{"word":"die Sonde","en":"probe","ru":"зонд (космический аппарат)","vi":"đầu dò","fa":"the probe","examples":[{"de":"Die Sonde sendete erstaunliche Bilder vom Saturn.","en":"The probe sent back astonishing images of Saturn.","ru":"Зонд прислал удивительные снимки Сатурна.","vi":"Tàu thăm dò đã gửi những hình ảnh tuyệt vời về Sao Thổ.","fa":"کاوشگر تصاویر شگفت انگیزی از زحل ارسال کرد."},{"de":"Eine Sonde fliegt jahrelang durch das Weltall.","en":"A probe flies through space for years.","ru":"Зонд годами летит сквозь космос.","vi":"Một tàu thăm dò bay trong không gian trong nhiều năm.","fa":"یک کاوشگر سال ها در فضا پرواز می کند."},{"de":"Die Sonde landete sanft auf dem Kometen.","en":"The probe landed gently on the comet.","ru":"Зонд мягко приземлился на комету.","vi":"Tàu thăm dò hạ cánh nhẹ nhàng trên sao chổi.","fa":"کاوشگر به آرامی روی دنباله دار فرود آمد."}]},{"word":"Sonder-","en":"special (prefix)","ru":"специальный, особый (приставка)","vi":"đặc biệt","fa":"خاص","examples":[{"de":"Wegen der Bauarbeiten fährt der Bus heute eine Sonderroute.","en":"Due to the construction work, the bus is taking a special route today.","ru":"Из-за строительных работ автобус сегодня едет по специальному маршруту.","vi":"Do đang thi công nên hôm nay xe buýt sẽ đi một tuyến đường đặc biệt.","fa":"به دلیل کار ساخت و ساز، اتوبوس امروز مسیر خاصی را طی می کند."},{"de":"Im Zug gibt es einen Sonderwagen für Familien.","en":"There is a special car for families on the train.","ru":"В поезде есть специальный вагон для семей.","vi":"Trên tàu có toa đặc biệt dành cho gia đình.","fa":"در قطار واگن مخصوص خانواده ها وجود دارد."}]},{"word":"das Sonderangebot","en":"special offer","ru":"специальное предложение, акция","vi":"ưu đãi đặc biệt","fa":"پیشنهاد ویژه","examples":[{"de":"Diese Woche gibt es im Supermarkt ein Sonderangebot für Kaffee.","en":"This week there is a special offer on coffee at the supermarket.","ru":"На этой неделе в супермаркете действует акция на кофе.","vi":"Tuần này có một ưu đãi đặc biệt về cà phê tại siêu thị.","fa":"این هفته یک پیشنهاد ویژه برای قهوه در سوپرمارکت وجود دارد."},{"de":"Ich habe die Jacke im Sonderangebot günstig gekauft.","en":"I bought the jacket cheaply as a special offer.","ru":"Я купил куртку недорого по акции.","vi":"Tôi đã mua chiếc áo khoác với giá rẻ nhờ ưu đãi đặc biệt.","fa":"من کت را ارزان در پیشنهاد ویژه خریدم."}]},{"word":"der Sondermüll","en":"hazardous waste","ru":"опасные отходы","vi":"chất thải nguy hại","fa":"زباله های خطرناک","examples":[{"de":"Alte Batterien gehören in den Sondermüll.","en":"Old batteries belong in the hazardous waste.","ru":"Старые батарейки относятся к опасным отходам.","vi":"Pin cũ thuộc chất thải nguy hại.","fa":"باتری های قدیمی جزو زباله های خطرناک هستند."},{"de":"Farben und Lacke sind Sondermüll.","en":"Paints and varnishes are hazardous waste.","ru":"Краски и лаки — это опасные отходы.","vi":"Sơn và vecni là chất thải nguy hại.","fa":"رنگ ها و لاک ها زباله های خطرناکی هستند."},{"de":"Sondermüll darf nicht in den normalen Abfall.","en":"Hazardous waste must not go in the normal rubbish.","ru":"Опасные отходы нельзя выбрасывать в обычный мусор.","vi":"Chất thải nguy hại không được phép vứt bỏ cùng với rác thải thông thường.","fa":"زباله های خطرناک را نمی توان با زباله های معمولی دفع کرد."}]},{"word":"sondern","en":"but (rather)","ru":"а, но (напротив)","vi":"nhưng","fa":"اما","examples":[{"de":"Ich trinke keinen Kaffee, sondern Tee.","en":"I don't drink coffee, but tea.","ru":"Я пью не кофе, а чай.","vi":"Tôi không uống cà phê, tôi uống trà.","fa":"من قهوه نمیخورم چای میخورم"},{"de":"Er ist nicht müde, sondern einfach nur gelangweilt.","en":"He isn't tired, but just bored.","ru":"Он не устал, а просто скучает.","vi":"Anh không mệt, chỉ là chán thôi.","fa":"او خسته نیست، فقط حوصله اش سر رفته است."}]},{"word":"die Sonne","en":"sun","ru":"солнце","vi":"mặt trời","fa":"خورشید","examples":[{"de":"Die Sonne scheint heute den ganzen Tag.","en":"The sun is shining all day today.","ru":"Сегодня солнце светит весь день.","vi":"Hôm nay mặt trời chiếu sáng cả ngày.","fa":"امروز تمام روز خورشید می درخشد."},{"de":"Wir haben uns in den Schatten gesetzt, weil die Sonne so stark schien.","en":"We sat in the shade because the sun was shining so strongly.","ru":"Мы сели в тень, потому что солнце светило так сильно.","vi":"Chúng tôi ngồi trong bóng râm vì nắng quá chói.","fa":"ما زیر سایه نشستیم زیرا خورشید به شدت می تابد."}]},{"word":"die Sonnencreme","en":"sun cream, sunscreen","ru":"солнцезащитный крем","vi":"kem chống nắng","fa":"ضد آفتاب","examples":[{"de":"Vergiss nicht, dich mit Sonnencreme einzucremen.","en":"Don't forget to put on sun cream.","ru":"Не забудь нанести солнцезащитный крем.","vi":"Đừng quên thoa kem chống nắng.","fa":"استفاده از ضد آفتاب را فراموش نکنید."},{"de":"Diese Sonnencreme hat einen hohen Schutzfaktor.","en":"This sun cream has a high protection factor.","ru":"У этого солнцезащитного крема высокий фактор защиты.","vi":"Kem chống nắng này có chỉ số bảo vệ cao.","fa":"این ضد آفتاب دارای فاکتور حفاظتی بالایی است."},{"de":"Am Strand braucht man unbedingt Sonnencreme.","en":"At the beach you definitely need sun cream.","ru":"На пляже обязательно нужен солнцезащитный крем.","vi":"Bạn chắc chắn cần kem chống nắng trên bãi biển.","fa":"حتما در ساحل به کرم ضد آفتاب نیاز دارید."}]},{"word":"der Sonnengruß","en":"sun salutation","ru":"приветствие солнцу (комплекс поз)","vi":"chào mặt trời","fa":"سلام خورشید","examples":[{"de":"Wir beginnen die Stunde mit dem Sonnengruß.","en":"We begin the class with the sun salutation.","ru":"Мы начинаем занятие с приветствия солнцу.","vi":"Chúng ta bắt đầu bài học bằng bài chào mặt trời.","fa":"درس را با سلام خورشید شروع می کنیم."},{"de":"Der Sonnengruß bringt mehrere Stellungen in einen Fluss.","en":"The sun salutation links several poses into one flow.","ru":"Приветствие солнцу объединяет несколько поз в один поток.","vi":"Động tác chào mặt trời kết hợp nhiều tư thế thành một.","fa":"سلام خورشید چندین حالت را در یک جریان می آورد."},{"de":"Am Morgen mache ich gern fünf Sonnengrüße.","en":"In the morning I like to do five sun salutations.","ru":"По утрам я люблю делать пять приветствий солнцу.","vi":"Vào buổi sáng, tôi thích thực hiện năm động tác chào mặt trời.","fa":"صبح ها دوست دارم پنج سلام بر آفتاب انجام دهم."}]},{"word":"die Sonnenstrahlung","en":"solar radiation","ru":"солнечное излучение","vi":"bức xạ mặt trời","fa":"the solar radiation","examples":[{"de":"Die Sonnenstrahlung erwärmt die Oberfläche der Erde.","en":"Solar radiation warms the surface of the Earth.","ru":"Солнечное излучение нагревает поверхность Земли.","vi":"Bức xạ mặt trời làm nóng bề mặt trái đất.","fa":"تابش خورشیدی سطح زمین را گرم می کند."},{"de":"Im Weltall ist die Sonnenstrahlung besonders stark.","en":"In space, solar radiation is especially strong.","ru":"В космосе солнечное излучение особенно сильное.","vi":"Bức xạ mặt trời đặc biệt mạnh trong không gian.","fa":"تابش خورشیدی به ویژه در فضا قوی است."},{"de":"Die Atmosphäre filtert einen Teil der Sonnenstrahlung.","en":"The atmosphere filters part of the solar radiation.","ru":"Атмосфера фильтрует часть солнечного излучения.","vi":"Bầu khí quyển lọc một số bức xạ mặt trời.","fa":"جو مقداری از تشعشعات خورشیدی را فیلتر می کند."}]},{"word":"das Sonnensystem","en":"solar system","ru":"Солнечная система","vi":"hệ mặt trời","fa":"منظومه شمسی","examples":[{"de":"Unser Sonnensystem besteht aus acht Planeten.","en":"Our solar system consists of eight planets.","ru":"Наша Солнечная система состоит из восьми планет.","vi":"Hệ mặt trời của chúng ta bao gồm tám hành tinh.","fa":"منظومه شمسی ما از هشت سیاره تشکیل شده است."},{"de":"Die Sonne steht im Zentrum des Sonnensystems.","en":"The Sun is at the centre of the solar system.","ru":"Солнце находится в центре Солнечной системы.","vi":"Mặt trời nằm ở trung tâm của hệ mặt trời.","fa":"خورشید در مرکز منظومه شمسی قرار دارد."},{"de":"Außerhalb unseres Sonnensystems gibt es viele weitere Sterne.","en":"Outside our solar system there are many more stars.","ru":"За пределами нашей Солнечной системы есть много других звёзд.","vi":"Có rất nhiều ngôi sao khác ngoài hệ mặt trời của chúng ta.","fa":"ستارگان زیادی در خارج از منظومه شمسی ما وجود دارند."}]},{"word":"sonst","en":"otherwise; else","ru":"иначе; а то","vi":"mặt khác","fa":"در غیر این صورت","examples":[{"de":"Beeil dich, sonst verpasst du den Bus.","en":"Hurry up, otherwise you'll miss the bus.","ru":"Поторопись, а то опоздаешь на автобус.","vi":"Nhanh lên nếu không bạn sẽ lỡ xe buýt.","fa":"عجله کنید وگرنه اتوبوس را از دست خواهید داد."},{"de":"Hast du sonst noch Fragen?","en":"Do you have any other questions?","ru":"У тебя есть ещё какие-нибудь вопросы?","vi":"Bạn có câu hỏi nào khác không?","fa":"آیا سوال دیگری دارید؟"}]},{"word":"die Sorge","en":"worry; concern","ru":"забота; беспокойство","vi":"sự lo lắng","fa":"نگرانی","examples":[{"de":"Mach dir keine Sorgen, alles wird gut.","en":"Don't worry, everything will be fine.","ru":"Не беспокойся, всё будет хорошо.","vi":"Đừng lo lắng, mọi thứ sẽ ổn thôi.","fa":"نگران نباش همه چی درست میشه"},{"de":"Die Eltern machten sich große Sorgen um ihr Kind.","en":"The parents were very worried about their child.","ru":"Родители очень беспокоились о своём ребёнке.","vi":"Cha mẹ rất lo lắng cho con mình.","fa":"والدین به شدت نگران فرزندشان بودند."}]},{"word":"sorgen","en":"to take care of; to see to (something)","ru":"заботиться (о ком-л./чём-л.)","vi":"lo lắng","fa":"نگرانی","examples":[{"de":"Meine Eltern sorgen für mich, solange ich studiere.","en":"My parents take care of me while I study.","ru":"Мои родители заботятся обо мне, пока я учусь.","vi":"Bố mẹ tôi sẽ chăm sóc tôi miễn là tôi học tập.","fa":"پدر و مادرم تا زمانی که درس می خوانم از من مراقبت خواهند کرد."},{"de":"Kannst du dafür sorgen, dass die Tür abgeschlossen ist?","en":"Can you make sure the door is locked?","ru":"Можешь позаботиться о том, чтобы дверь была заперта?","vi":"Bạn có thể chắc chắn rằng cửa đã khóa?","fa":"آیا می توانید مطمئن شوید که در قفل است؟"}]},{"word":"sorgfältig","en":"careful, thorough","ru":"тщательный, аккуратный, добросовестный","vi":"cẩn thận","fa":"با دقت","examples":[{"de":"Sie arbeitet immer sehr sorgfältig.","en":"She always works very carefully.","ru":"Она всегда работает очень тщательно.","vi":"Cô ấy luôn làm việc rất cẩn thận.","fa":"او همیشه با دقت کار می کند."},{"de":"Lies den Vertrag sorgfältig durch.","en":"Read the contract through carefully.","ru":"Внимательно прочитай договор.","vi":"Đọc kỹ hợp đồng.","fa":"قرارداد را با دقت بخوانید."},{"de":"Eine sorgfältige Vorbereitung spart später Zeit.","en":"Careful preparation saves time later.","ru":"Тщательная подготовка экономит время потом.","vi":"Chuẩn bị kỹ lưỡng sẽ tiết kiệm thời gian sau này.","fa":"آماده سازی دقیق باعث صرفه جویی در زمان بعد می شود."}]},{"word":"die Soße/Sauce","en":"sauce; gravy","ru":"соус","vi":"nước xốt/nước sốt","fa":"سس / سس","examples":[{"de":"Die Nudeln schmecken mit dieser Soße besonders gut.","en":"The pasta tastes especially good with this sauce.","ru":"Паста особенно вкусна с этим соусом.","vi":"Mì có hương vị đặc biệt ngon với nước sốt này.","fa":"نودل ها با این سس طعم خوبی دارند."},{"de":"Sie hat die Sauce selbst gekocht.","en":"She made the sauce herself.","ru":"Она сама приготовила соус.","vi":"Cô ấy tự làm nước sốt.","fa":"سس را خودش درست کرد."}]},{"word":"das Souvenir","en":"souvenir","ru":"сувенир","vi":"quà lưu niệm","fa":"سوغات","examples":[{"de":"Wir haben ein Souvenir aus Wien mitgebracht.","en":"We brought back a souvenir from Vienna.","ru":"Мы привезли сувенир из Вены.","vi":"Chúng tôi mang theo một món quà lưu niệm từ Vienna.","fa":"از وین با خودمان سوغاتی آوردیم."},{"de":"Auf dem Markt gibt es viele kleine Souvenirs.","en":"There are many small souvenirs at the market.","ru":"На рынке много маленьких сувениров.","vi":"Có rất nhiều món quà lưu niệm nhỏ trên thị trường.","fa":"سوغاتی های کوچک زیادی در بازار وجود دارد."}]},{"word":"soviel","en":"as far as (soviel ich weiß = as far as I know)","ru":"насколько (soviel ich weiß = насколько я знаю)","vi":"rất nhiều","fa":"خیلی","examples":[{"de":"Soviel ich weiß, kommt er morgen.","en":"As far as I know, he's coming tomorrow.","ru":"Насколько я знаю, он придёт завтра.","vi":"As far as I know, he's coming tomorrow.","fa":"تا اونجایی که من میدونم فردا میاد"},{"de":"Soviel ich gehört habe, ist der Laden geschlossen.","en":"As far as I've heard, the shop is closed.","ru":"Насколько я слышал, магазин закрыт.","vi":"Theo những gì tôi nghe được thì cửa hàng đã đóng cửa.","fa":"طبق شنیده ها فروشگاه تعطیل است."}]},{"word":"sowieso","en":"anyway; in any case","ru":"всё равно; в любом случае","vi":"dù sao đi nữa","fa":"به هر حال","examples":[{"de":"Ich wollte sowieso einkaufen gehen.","en":"I wanted to go shopping anyway.","ru":"Я всё равно собирался идти за покупками.","vi":"Dù sao thì tôi cũng muốn đi mua sắm.","fa":"به هر حال می خواستم برم خرید."},{"de":"Es ist sowieso zu spät, um heute noch anzufangen.","en":"It's too late to start today anyway.","ru":"В любом случае, уже слишком поздно начинать сегодня.","vi":"Đó là điều tôi muốn nói, um heute noch anzufangen.","fa":"به هر حال برای شروع امروز خیلی دیر است."}]},{"word":"sowohl","en":"both ... (and) (sowohl ... als auch)","ru":"как... (так и) (sowohl ... als auch — как ... так и)","vi":"cả hai","fa":"هر دو","examples":[{"de":"Sie spricht sowohl Englisch als auch Spanisch.","en":"She speaks both English and Spanish.","ru":"Она говорит как по-английски, так и по-испански.","vi":"Cô ấy nói được cả tiếng Anh và tiếng Tây Ban Nha.","fa":"او به دو زبان انگلیسی و اسپانیایی صحبت می کند."},{"de":"Sowohl die Kinder als auch die Eltern waren zufrieden.","en":"Both the children and the parents were satisfied.","ru":"Как дети, так и родители были довольны.","vi":"Cả trẻ em và cha mẹ đều hài lòng.","fa":"هم بچه ها و هم والدین راضی بودند."},{"de":"Das Café bietet sowohl Kaffee als auch Tee an.","en":"The café offers both coffee and tea.","ru":"В кафе подают как кофе, так и чай.","vi":"Quán cà phê cung cấp cả cà phê và trà.","fa":"در این کافه هم قهوه و هم چای ارائه می شود."}]},{"word":"sowohl … als auch","en":"both ... and","ru":"как ..., так и ...","vi":"cả...và","fa":"هر دو ... و","examples":[{"de":"Sie spricht sowohl Deutsch als auch Englisch.","en":"She speaks both German and English.","ru":"Она говорит как по-немецки, так и по-английски.","vi":"Cô ấy nói được cả tiếng Đức và tiếng Anh.","fa":"او به دو زبان آلمانی و انگلیسی صحبت می کند."},{"de":"Sowohl meine Mutter als auch mein Vater arbeiten in der Stadt.","en":"Both my mother and my father work in the city.","ru":"Как моя мать, так и мой отец работают в городе.","vi":"Cả bố và mẹ tôi đều làm việc ở thành phố.","fa":"مادر و پدرم هر دو در شهر کار می کنند."}]},{"word":"sozial","en":"social","ru":"социальный","vi":"xã hội","fa":"اجتماعی","examples":[{"de":"Er engagiert sich für soziale Projekte.","en":"He is involved in social projects.","ru":"Он занимается социальными проектами.","vi":"Anh ấy cam kết thực hiện các dự án xã hội.","fa":"او به پروژه های اجتماعی متعهد است."},{"de":"Die sozialen Unterschiede sind in dieser Stadt groß.","en":"The social differences in this city are large.","ru":"Социальные различия в этом городе велики.","vi":"Sự khác biệt xã hội là rất lớn ở thành phố này.","fa":"تفاوت های اجتماعی در این شهر زیاد است."}]},{"word":"der Sozialarbeiter","en":"social worker (male)","ru":"социальный работник (мужчина)","vi":"nhân viên xã hội","fa":"مددکار اجتماعی","examples":[{"de":"Der Sozialarbeiter hilft Familien in schwierigen Situationen.","en":"The social worker helps families in difficult situations.","ru":"Социальный работник помогает семьям в трудных ситуациях.","vi":"Nhân viên xã hội giúp đỡ các gia đình có hoàn cảnh khó khăn.","fa":"مددکار اجتماعی به خانواده ها در شرایط سخت کمک می کند."},{"de":"Mein Bruder arbeitet als Sozialarbeiter in einem Jugendzentrum.","en":"My brother works as a social worker in a youth centre.","ru":"Мой брат работает социальным работником в молодёжном центре.","vi":"Anh trai tôi làm nhân viên xã hội ở một trung tâm thanh thiếu niên.","fa":"برادرم به عنوان مددکار اجتماعی در مرکز جوانان کار می کند."},{"de":"Der Sozialarbeiter hat ein langes Gespräch mit dem Jungen geführt.","en":"The social worker had a long conversation with the boy.","ru":"Социальный работник долго разговаривал с мальчиком.","vi":"Nhân viên xã hội đã có một cuộc trò chuyện dài với cậu bé.","fa":"مددکار اجتماعی گفت و گوی طولانی با پسر داشت."}]},{"word":"die Sozialarbeiterin","en":"social worker (female)","ru":"социальный работник (женщина)","vi":"nhân viên xã hội","fa":"مددکار اجتماعی","examples":[{"de":"Die Sozialarbeiterin hilft Familien in schwierigen Situationen.","en":"The social worker helps families in difficult situations.","ru":"Социальный работник помогает семьям в трудных ситуациях.","vi":"Nhân viên xã hội giúp đỡ các gia đình có hoàn cảnh khó khăn.","fa":"مددکار اجتماعی به خانواده ها در شرایط سخت کمک می کند."},{"de":"Sie arbeitet seit fünf Jahren als Sozialarbeiterin.","en":"She has been working as a social worker for five years.","ru":"Она работает социальным работником уже пять лет.","vi":"Cô đã làm nhân viên xã hội được 5 năm.","fa":"او پنج سال است که به عنوان مددکار اجتماعی کار می کند."}]},{"word":"spannend","en":"exciting; suspenseful","ru":"увлекательный; захватывающий","vi":"thú vị","fa":"هیجان انگیز","examples":[{"de":"Der Film war wirklich spannend.","en":"The movie was really exciting.","ru":"Фильм был по-настоящему захватывающим.","vi":"Der Film war wirklich spannend.","fa":"فیلم واقعا هیجان انگیز بود."},{"de":"Sie liest gerade ein spannendes Buch.","en":"She's currently reading an exciting book.","ru":"Она сейчас читает увлекательную книгу.","vi":"Cô ấy hiện đang đọc một cuốn sách thú vị.","fa":"او در حال حاضر در حال خواندن یک کتاب هیجان انگیز است."}]},{"word":"das Sparbuch","en":"savings book","ru":"сберегательная книжка","vi":"sổ tiết kiệm","fa":"the savings book","examples":[{"de":"Als Kind hatte ich ein Sparbuch von meiner Oma.","en":"As a child I had a savings book from my grandmother.","ru":"В детстве у меня была сберегательная книжка от бабушки.","vi":"Khi còn nhỏ, tôi có một tài khoản tiết kiệm từ bà ngoại.","fa":"از بچگی از مادربزرگم حساب پس انداز داشتم."},{"de":"Auf dem Sparbuch gibt es kaum noch Zinsen.","en":"There is hardly any interest on a savings book anymore.","ru":"На сберегательной книжке почти нет процентов.","vi":"Hầu như không có lãi suất trên tài khoản tiết kiệm.","fa":"به ندرت سودی در حساب پس انداز وجود دارد."},{"de":"Er legte das Geld auf ein Sparbuch.","en":"He put the money into a savings book.","ru":"Он положил деньги на сберегательную книжку.","vi":"Anh ta gửi tiền vào tài khoản tiết kiệm.","fa":"او پول را در یک حساب پس انداز گذاشت."}]},{"word":"sparen","en":"to save (money/time)","ru":"экономить; копить","vi":"lưu lại","fa":"ذخیره کنید","examples":[{"de":"Wir sparen Geld für den Urlaub.","en":"We're saving money for vacation.","ru":"Мы копим деньги на отпуск.","vi":"Chúng tôi tiết kiệm tiền cho kỳ nghỉ.","fa":"ما برای تعطیلات پول پس انداز می کنیم."},{"de":"Man kann viel Energie sparen, wenn man das Licht ausschaltet.","en":"You can save a lot of energy by turning off the light.","ru":"Можно сэкономить много энергии, выключая свет.","vi":"Bạn có thể tiết kiệm rất nhiều năng lượng bằng cách tắt đèn.","fa":"با خاموش کردن چراغ ها می توانید در مصرف انرژی صرفه جویی کنید."}]},{"word":"das Sparkonto","en":"savings account","ru":"сберегательный счёт","vi":"tài khoản tiết kiệm","fa":"the savings account","examples":[{"de":"Ich lege jeden Monat etwas Geld auf mein Sparkonto.","en":"I put some money into my savings account every month.","ru":"Каждый месяц я откладываю немного денег на сберегательный счёт.","vi":"Tôi gửi một ít tiền vào tài khoản tiết kiệm hàng tháng.","fa":"من هر ماه مقداری پول به حساب پس اندازم می گذارم."},{"de":"Auf dem Sparkonto bekommt man kaum noch Zinsen.","en":"You hardly get any interest on a savings account anymore.","ru":"На сберегательном счёте почти не получаешь процентов.","vi":"Bạn hầu như không nhận được tiền lãi từ tài khoản tiết kiệm của mình.","fa":"شما به سختی سودی در حساب پس انداز خود دریافت می کنید."},{"de":"Für den Urlaub habe ich auf meinem Sparkonto gespart.","en":"I have saved up for the holiday in my savings account.","ru":"Я копил на отпуск на своём сберегательном счёте.","vi":"Tôi đã tiết kiệm cho kỳ nghỉ trong tài khoản tiết kiệm của mình.","fa":"من برای تعطیلات در حساب پس اندازم ذخیره کردم."}]},{"word":"sparsam","en":"economical, thrifty, sparing","ru":"экономный, бережливый","vi":"kinh tế","fa":"اقتصادی","examples":[{"de":"Wir gehen sparsam mit Wasser und Strom um.","en":"We use water and electricity sparingly.","ru":"Мы экономно обращаемся с водой и электричеством.","vi":"Chúng tôi sử dụng nước và điện một cách tiết kiệm.","fa":"از آب و برق کم استفاده می کنیم."},{"de":"Ein sparsames Auto verbraucht weniger Benzin.","en":"An economical car uses less petrol.","ru":"Экономная машина потребляет меньше бензина.","vi":"Một chiếc xe tiết kiệm sử dụng ít xăng hơn.","fa":"یک خودروی اقتصادی بنزین کمتری مصرف می کند."},{"de":"Sei bitte sparsam mit dem warmen Wasser.","en":"Please be sparing with the hot water.","ru":"Пожалуйста, будь экономен с горячей водой.","vi":"Hãy cẩn thận với nước ấm.","fa":"لطفا مراقب آب گرم باشید."}]},{"word":"der Spaß","en":"fun","ru":"удовольствие; веселье","vi":"niềm vui","fa":"سرگرمی","examples":[{"de":"Das Spiel macht den Kindern großen Spaß.","en":"The game is a lot of fun for the children.","ru":"Игра доставляет детям огромное удовольствие.","vi":"Trò chơi mang lại niềm vui lớn cho trẻ em.","fa":"این بازی برای کودکان بسیار سرگرم کننده است."},{"de":"Viel Spaß beim Feiern!","en":"Have fun at the party!","ru":"Хорошо повеселиться на празднике!","vi":"Have fun celebrating!","fa":"از جشن گرفتن لذت ببرید!"}]},{"word":"spät","en":"late","ru":"поздний; поздно","vi":"muộn","fa":"دیر","examples":[{"de":"Es ist schon spät, wir sollten nach Hause gehen.","en":"It's already late, we should go home.","ru":"Уже поздно, нам пора домой.","vi":"Đã muộn rồi, chúng ta nên về nhà thôi.","fa":"دیر شده باید بریم خونه"},{"de":"Er kommt oft zu spät zur Arbeit.","en":"He often comes to work too late.","ru":"Он часто опаздывает на работу.","vi":"Anh ấy thường xuyên đi làm muộn.","fa":"او اغلب دیر سر کار می آید."}]},{"word":"spätestens","en":"at the latest","ru":"самое позднее, не позднее","vi":"muộn nhất","fa":"در آخرین","examples":[{"de":"Wir treffen uns spätestens um acht Uhr.","en":"We'll meet at eight o'clock at the latest.","ru":"Мы встретимся самое позднее в восемь.","vi":"Chúng ta sẽ gặp nhau muộn nhất lúc tám giờ.","fa":"حداکثر ساعت هشت همدیگر را خواهیم دید."},{"de":"Das Paket kommt spätestens morgen an.","en":"The parcel will arrive tomorrow at the latest.","ru":"Посылка придёт самое позднее завтра.","vi":"Gói hàng sẽ đến muộn nhất vào ngày mai.","fa":"بسته حداکثر فردا می رسد."},{"de":"Spätestens nächste Woche muss ich abgeben.","en":"I have to hand it in next week at the latest.","ru":"Я должен сдать это самое позднее на следующей неделе.","vi":"Chậm nhất là tuần sau tôi phải nộp nó.","fa":"حداکثر هفته آینده باید تحویلش بدم."}]},{"word":"spazieren gehen","en":"to go for a walk","ru":"гулять; идти на прогулку","vi":"đi dạo","fa":"برو پیاده روی","examples":[{"de":"Am Sonntag gehen wir im Park spazieren.","en":"On Sunday we go for a walk in the park.","ru":"В воскресенье мы гуляем в парке.","vi":"Chủ nhật chúng tôi đi dạo trong công viên.","fa":"یکشنبه میریم تو پارک قدم بزنیم."},{"de":"Nach dem Essen gehen sie gerne spazieren.","en":"After eating they like to go for a walk.","ru":"После еды они любят гулять.","vi":"Họ thích đi dạo sau khi ăn xong.","fa":"آنها دوست دارند بعد از صرف غذا به پیاده روی بروند."}]},{"word":"der Speicher","en":"memory; storage","ru":"память, хранилище (данных)","vi":"ký ức","fa":"حافظه","examples":[{"de":"Auf meinem Handy ist der Speicher fast voll.","en":"The storage on my phone is almost full.","ru":"На моём телефоне память почти заполнена.","vi":"Bộ nhớ trên điện thoại của tôi gần đầy.","fa":"حافظه گوشی من تقریبا پر شده است."},{"de":"Das Programm braucht sehr viel Speicher.","en":"The program needs a great deal of memory.","ru":"Программе нужно очень много памяти.","vi":"Chương trình đòi hỏi nhiều bộ nhớ.","fa":"این برنامه به حافظه زیادی نیاز دارد."},{"de":"Du kannst zusätzlichen Speicher in der Cloud kaufen.","en":"You can buy additional storage in the cloud.","ru":"Дополнительное хранилище можно купить в облаке.","vi":"Bạn có thể mua thêm dung lượng lưu trữ trên đám mây.","fa":"می توانید فضای ذخیره سازی اضافی را در فضای ابری خریداری کنید."}]},{"word":"speichern","en":"to save (data)","ru":"сохранять (данные)","vi":"cứu","fa":"ذخیره کنید","examples":[{"de":"Vergiss nicht, das Dokument zu speichern.","en":"Don't forget to save the document.","ru":"Не забудь сохранить документ.","vi":"Đừng quên lưu tài liệu.","fa":"فراموش نکنید که سند را ذخیره کنید."},{"de":"Die Fotos werden automatisch auf dem Handy gespeichert.","en":"The photos are automatically saved on the phone.","ru":"Фотографии автоматически сохраняются на телефоне.","vi":"Các bức ảnh sẽ được lưu tự động trên điện thoại.","fa":"عکس ها به صورت خودکار در گوشی ذخیره می شوند."}]},{"word":"Speise-/-speise","en":"food; dish (combining form, e.g. Speisekarte = menu)","ru":"еда; блюдо (словообразовательный элемент, напр. Speisekarte = меню)","vi":"Thức ăn/món ăn","fa":"غذا / ظرف","examples":[{"de":"Der Kellner bringt uns die Speisekarte.","en":"The waiter brings us the menu.","ru":"Официант приносит нам меню.","vi":"Người phục vụ mang thực đơn đến cho chúng tôi.","fa":"پیشخدمت منو می آورد."},{"de":"Im Speisewagen des Zuges kann man essen.","en":"You can eat in the dining car of the train.","ru":"В вагоне-ресторане поезда можно поесть.","vi":"Bạn có thể ăn trong toa ăn của tàu.","fa":"می توانید در واگن ناهار خوری قطار غذا بخورید."}]},{"word":"der Speisewagen","en":"dining car (on a train)","ru":"вагон-ресторан","vi":"xe ăn uống","fa":"ماشین غذاخوری","examples":[{"de":"Im Speisewagen kann man warme Mahlzeiten bekommen.","en":"In the dining car you can get hot meals.","ru":"В вагоне-ресторане можно получить горячую еду.","vi":"Bạn có thể thưởng thức những bữa ăn nóng hổi trong toa ăn.","fa":"می توانید غذای گرم را در ماشین ناهار خوری میل کنید."},{"de":"Wir sind in den Speisewagen gegangen, um zu frühstücken.","en":"We went to the dining car to have breakfast.","ru":"Мы пошли в вагон-ресторан позавтракать.","vi":"Chúng tôi ra toa ăn để ăn sáng.","fa":"برای صرف صبحانه به سمت ماشین غذاخوری رفتیم."},{"de":"Der Speisewagen befindet sich in der Mitte des Zuges.","en":"The dining car is located in the middle of the train.","ru":"Вагон-ресторан находится в середине поезда.","vi":"Toa ăn nằm ở giữa đoàn tàu.","fa":"ماشین ناهار خوری وسط قطار است."}]},{"word":"die Spende","en":"donation","ru":"пожертвование","vi":"sự quyên góp","fa":"کمک مالی","examples":[{"de":"Mit einer kleinen Spende kann man viel bewirken.","en":"You can achieve a lot with a small donation.","ru":"Небольшим пожертвованием можно многого добиться.","vi":"Với một khoản đóng góp nhỏ, bạn có thể tạo ra sự khác biệt lớn.","fa":"با یک کمک مالی کوچک می توانید تفاوت بزرگی ایجاد کنید."},{"de":"Die Organisation lebt von Spenden.","en":"The organisation survives on donations.","ru":"Организация живёт за счёт пожертвований.","vi":"Tổ chức này sống nhờ vào sự quyên góp.","fa":"این سازمان از کمک های مالی زندگی می کند."}]},{"word":"der Sperrmüll","en":"bulky waste, oversized rubbish","ru":"крупногабаритный мусор","vi":"chất thải cồng kềnh","fa":"زباله های حجیم","examples":[{"de":"Den alten Schrank stellen wir zum Sperrmüll.","en":"We'll put the old wardrobe out for bulky waste collection.","ru":"Старый шкаф мы вынесем на крупногабаритный мусор.","vi":"Chúng tôi bỏ chiếc tủ cũ vào thùng rác.","fa":"کمد قدیمی را داخل سطل زباله گذاشتیم."},{"de":"Der Sperrmüll wird nächsten Dienstag abgeholt.","en":"The bulky waste will be collected next Tuesday.","ru":"Крупногабаритный мусор вывезут в следующий вторник.","vi":"Rác cồng kềnh sẽ được thu gom vào thứ Ba tới.","fa":"زباله های حجیم سه شنبه آینده جمع آوری می شود."},{"de":"Man darf Sperrmüll nicht einfach auf die Straße stellen.","en":"You're not allowed to simply put bulky waste out on the street.","ru":"Крупногабаритный мусор нельзя просто выставлять на улицу.","vi":"Bạn không thể cứ vứt rác thải cồng kềnh ra đường được.","fa":"شما نمی توانید زباله های حجیم را در خیابان بریزید."}]},{"word":"Spezial-","en":"special (combining form, e.g. Spezialangebot = special offer)","ru":"специальный (словообразовательный элемент, напр. Spezialangebot = специальное предложение)","vi":"đặc biệt","fa":"خاص","examples":[{"de":"Der Supermarkt hat diese Woche ein Spezialangebot.","en":"The supermarket has a special offer this week.","ru":"В супермаркете на этой неделе специальное предложение.","vi":"Tuần này siêu thị có ưu đãi đặc biệt.","fa":"سوپرمارکت این هفته یک پیشنهاد ویژه دارد."},{"de":"Er ist Arzt und hat ein Spezialgebiet für Kinderkrankheiten.","en":"He is a doctor and has a specialty in children's diseases.","ru":"Он врач и специализируется на детских болезнях.","vi":"Ông là bác sĩ và chuyên về bệnh trẻ em.","fa":"او پزشک است و متخصص بیماری های کودکان است."}]},{"word":"die Spezialisierung","en":"specialisation","ru":"специализация","vi":"chuyên môn","fa":"تخصص","examples":[{"de":"Seine Spezialisierung ist die Behandlung von Kindern.","en":"His specialisation is the treatment of children.","ru":"Его специализация — лечение детей.","vi":"Chuyên môn của anh là chữa bệnh cho trẻ em.","fa":"تخصص او درمان کودکان است."},{"de":"Eine Spezialisierung kann die Berufschancen verbessern.","en":"A specialisation can improve your career prospects.","ru":"Специализация может улучшить карьерные перспективы.","vi":"Chuyên môn hóa có thể cải thiện triển vọng nghề nghiệp.","fa":"تخصص می تواند آینده شغلی را بهبود بخشد."},{"de":"Im letzten Studienjahr wählt man eine Spezialisierung.","en":"In the final year of study you choose a specialisation.","ru":"На последнем году обучения вы выбираете специализацию.","vi":"Vào năm học cuối cùng bạn chọn một chuyên ngành.","fa":"در سال آخر تحصیل شما یک رشته تخصصی را انتخاب می کنید."}]},{"word":"der Spezialist","en":"specialist, expert (male)","ru":"специалист, эксперт (мужчина)","vi":"chuyên gia","fa":"متخصص","examples":[{"de":"Bei diesem Problem brauchen wir einen Spezialisten.","en":"For this problem we need a specialist.","ru":"Для этой проблемы нам нужен специалист.","vi":"Chúng tôi cần một chuyên gia cho vấn đề này.","fa":"برای این مشکل به متخصص نیاز داریم."},{"de":"Er ist ein Spezialist für alte Computer.","en":"He is a specialist in old computers.","ru":"Он специалист по старым компьютерам.","vi":"Anh ấy là chuyên gia về máy tính cũ.","fa":"او متخصص کامپیوترهای قدیمی است."},{"de":"Der Spezialist erklärte uns alles ganz genau.","en":"The specialist explained everything to us very precisely.","ru":"Специалист всё нам очень точно объяснил.","vi":"Chuyên gia đã giải thích mọi thứ cho chúng tôi một cách chi tiết.","fa":"متخصص همه چیز را با جزئیات برای ما توضیح داد."}]},{"word":"die Spezialistin","en":"specialist, expert (female)","ru":"специалистка, эксперт (женщина)","vi":"chuyên gia","fa":"متخصص","examples":[{"de":"Sie ist eine bekannte Spezialistin für Herzkrankheiten.","en":"She is a well-known specialist in heart diseases.","ru":"Она известный специалист по болезням сердца.","vi":"Cô ấy là một chuyên gia về bệnh tim nổi tiếng.","fa":"او یک متخصص شناخته شده بیماری های قلبی است."},{"de":"Die Spezialistin hat sofort die richtige Diagnose gestellt.","en":"The specialist immediately made the correct diagnosis.","ru":"Специалистка сразу поставила верный диагноз.","vi":"Chuyên gia ngay lập tức đưa ra chẩn đoán chính xác.","fa":"متخصص بلافاصله تشخیص صحیح را داد."},{"de":"Wir haben eine Spezialistin um Rat gefragt.","en":"We asked a specialist for advice.","ru":"Мы попросили совета у специалистки.","vi":"Chúng tôi đã nhờ một chuyên gia cho lời khuyên.","fa":"از یک متخصص راهنمایی خواستیم."}]},{"word":"speziell","en":"special; specific","ru":"особый; специальный","vi":"đặc biệt","fa":"خاص","examples":[{"de":"Für dieses Problem brauchen wir eine spezielle Lösung.","en":"We need a special solution for this problem.","ru":"Для этой проблемы нам нужно особое решение.","vi":"Chúng ta cần một giải pháp đặc biệt cho vấn đề này.","fa":"برای این مشکل به یک راه حل ویژه نیاز داریم."},{"de":"Sie hat spezielle Wünsche für das Essen.","en":"She has specific requests for the food.","ru":"У неё особые пожелания насчёт еды.","vi":"Cô ấy có những yêu cầu đặc biệt về đồ ăn.","fa":"او درخواست های ویژه ای برای غذا دارد."}]},{"word":"der Spickzettel","en":"crib sheet, cheat sheet","ru":"шпаргалка","vi":"bảng gian lận","fa":"برگه تقلب","examples":[{"de":"Der Lehrer hat den Spickzettel sofort entdeckt.","en":"The teacher spotted the crib sheet immediately.","ru":"Учитель сразу заметил шпаргалку.","vi":"Giáo viên phát hiện ra bảng cheat ngay lập tức.","fa":"معلم بلافاصله برگه تقلب را دید."},{"de":"In der Prüfung sind Spickzettel natürlich verboten.","en":"In the exam crib sheets are of course forbidden.","ru":"На экзамене шпаргалки, конечно, запрещены.","vi":"Tất nhiên, cheat sheet bị cấm trong kỳ thi.","fa":"البته تقلب در آزمون ممنوع است."},{"de":"Sie hatte einen kleinen Spickzettel im Ärmel versteckt.","en":"She had hidden a little crib sheet in her sleeve.","ru":"Она спрятала маленькую шпаргалку в рукаве.","vi":"Cô ấy có một tờ giấy nhỏ giấu trong tay áo.","fa":"او یک برگه تقلب کوچک در آستین خود پنهان کرده بود."}]},{"word":"der Spiegel","en":"mirror","ru":"зеркало","vi":"cái gương","fa":"آینه","examples":[{"de":"Sie schaut sich im Spiegel an.","en":"She looks at herself in the mirror.","ru":"Она смотрит на себя в зеркало.","vi":"Cô nhìn mình trong gương.","fa":"او در آینه به خود نگاه می کند."},{"de":"Der Spiegel im Bad ist zu klein.","en":"The mirror in the bathroom is too small.","ru":"Зеркало в ванной слишком маленькое.","vi":"Gương trong phòng tắm quá nhỏ.","fa":"آینه حمام خیلی کوچک است."}]},{"word":"das Spiel","en":"game, play, match","ru":"игра; матч","vi":"trò chơi","fa":"بازی","examples":[{"de":"Das Spiel hat den Kindern großen Spaß gemacht.","en":"The game was great fun for the children.","ru":"Игра доставила детям большое удовольствие.","vi":"Các em đã có rất nhiều niềm vui với trò chơi.","fa":"بچه ها از بازی خیلی لذت بردند."},{"de":"Unsere Mannschaft hat das Spiel knapp gewonnen.","en":"Our team narrowly won the match.","ru":"Наша команда с трудом выиграла матч.","vi":"Đội của chúng tôi đã giành chiến thắng trong trò chơi trong gang tấc.","fa":"تیم ما بازی را با اختلاف کمی برد."},{"de":"Nach dem Spiel waren alle Spieler erschöpft.","en":"After the match all the players were exhausted.","ru":"После матча все игроки были измотаны.","vi":"Sau trận đấu, tất cả người chơi đều kiệt sức.","fa":"بعد از بازی همه بازیکنان خسته بودند."}]},{"word":"spielen","en":"to play","ru":"играть","vi":"chơi","fa":"بازی کردن","examples":[{"de":"Die Kinder spielen im Garten.","en":"The children are playing in the garden.","ru":"Дети играют в саду.","vi":"Bọn trẻ đang chơi trong vườn.","fa":"بچه ها در باغ بازی می کنند."},{"de":"Er spielt seit Jahren Gitarre.","en":"He has been playing guitar for years.","ru":"Он играет на гитаре уже много лет.","vi":"Anh ấy đã chơi guitar được nhiều năm.","fa":"او سال هاست که گیتار می نوازد."}]},{"word":"der Spieler","en":"player (male)","ru":"игрок (мужчина)","vi":"người chơi","fa":"بازیکن","examples":[{"de":"Der Spieler hat das entscheidende Tor geschossen.","en":"The player scored the decisive goal.","ru":"Игрок забил решающий гол.","vi":"Cầu thủ này đã ghi bàn thắng quyết định.","fa":"این بازیکن گل تعیین کننده را به ثمر رساند."},{"de":"Jeder Spieler bekommt fünf Karten.","en":"Each player gets five cards.","ru":"Каждый игрок получает по пять карт.","vi":"Mỗi người chơi nhận được năm thẻ.","fa":"هر بازیکن پنج کارت دریافت می کند."},{"de":"Der beste Spieler des Teams ist verletzt.","en":"The best player on the team is injured.","ru":"Лучший игрок команды травмирован.","vi":"Cầu thủ xuất sắc nhất của đội bị chấn thương.","fa":"بهترین بازیکن تیم مصدوم است."}]},{"word":"die Spielerin","en":"player (female)","ru":"игрок (женщина)","vi":"người chơi","fa":"بازیکن","examples":[{"de":"Die Spielerin gewann das wichtige Turnier.","en":"The player won the important tournament.","ru":"Игрок выиграла важный турнир.","vi":"Người chơi đã thắng giải đấu quan trọng.","fa":"این بازیکن در تورنمنت مهم قهرمان شد."},{"de":"Sie ist die jüngste Spielerin in der Mannschaft.","en":"She is the youngest player on the team.","ru":"Она самая молодая игрок в команде.","vi":"Cô ấy là cầu thủ trẻ nhất trong đội.","fa":"او جوان ترین بازیکن تیم است."},{"de":"Die Spielerin warf den Ball über das Netz.","en":"The player threw the ball over the net.","ru":"Игрок перебросила мяч через сетку.","vi":"Cầu thủ này đã ném bóng qua lưới.","fa":"بازیکن توپ را روی تور پرتاب کرد."}]},{"word":"der Spielplatz","en":"playground","ru":"детская площадка","vi":"sân chơi","fa":"زمین بازی","examples":[{"de":"Die Kinder spielen den ganzen Nachmittag auf dem Spielplatz.","en":"The children play on the playground all afternoon.","ru":"Дети играют на детской площадке весь день.","vi":"Bọn trẻ chơi ở sân chơi suốt buổi chiều.","fa":"بچه ها تمام بعد از ظهر در زمین بازی بازی می کنند."},{"de":"In der Nähe unserer Wohnung gibt es einen großen Spielplatz.","en":"There is a big playground near our flat.","ru":"Рядом с нашей квартирой есть большая детская площадка.","vi":"Có một sân chơi lớn gần căn hộ của chúng tôi.","fa":"یک زمین بازی بزرگ در نزدیکی آپارتمان ما وجود دارد."},{"de":"Der neue Spielplatz hat eine tolle Rutsche.","en":"The new playground has a great slide.","ru":"На новой детской площадке отличная горка.","vi":"Sân chơi mới có cầu trượt tuyệt vời.","fa":"زمین بازی جدید دارای یک سرسره عالی است."}]},{"word":"das Spielzeug","en":"toy, toys","ru":"игрушка, игрушки","vi":"đồ chơi","fa":"اسباب بازی","examples":[{"de":"Das Kind hat viel zu viel Spielzeug.","en":"The child has far too many toys.","ru":"У ребёнка слишком много игрушек.","vi":"Bé có quá nhiều đồ chơi","fa":"کودک اسباب بازی های بسیار زیادی دارد."},{"de":"Räum bitte dein Spielzeug auf!","en":"Please tidy up your toys!","ru":"Убери, пожалуйста, свои игрушки!","vi":"Hãy dọn dẹp đồ chơi của bạn!","fa":"لطفا اسباب بازی های خود را تمیز کنید!"},{"de":"Dieses Spielzeug ist für kleine Kinder nicht geeignet.","en":"This toy is not suitable for small children.","ru":"Эта игрушка не подходит для маленьких детей.","vi":"Đồ chơi này không phù hợp với trẻ nhỏ.","fa":"این اسباب بازی برای کودکان کوچک مناسب نیست."}]},{"word":"spitz","en":"pointed; sharp","ru":"острый; заострённый","vi":"nhọn","fa":"اشاره کرد","examples":[{"de":"Pass auf, das Messer ist spitz!","en":"Be careful, the knife is sharp!","ru":"Осторожно, нож острый!","vi":"Hãy cẩn thận, con dao rất sắc!","fa":"مراقب باشید، چاقو تیز است!"},{"de":"Der Turm hat ein spitzes Dach.","en":"The tower has a pointed roof.","ru":"У башни остроконечная крыша.","vi":"Tháp có mái nhọn.","fa":"برج سقفی نوک تیز دارد."}]},{"word":"die Spitze","en":"point, tip (e.g. dancing on points)","ru":"носок, кончик (напр. танцевать на носках)","vi":"đỉnh cao","fa":"بالا","examples":[{"de":"Die Tänzerin drehte sich auf der Spitze ihres Fußes.","en":"The dancer turned on the tip of her foot.","ru":"Танцовщица повернулась на кончике стопы.","vi":"Cô vũ công xoay người trên đầu bàn chân.","fa":"رقصنده روی نوک پایش چرخید."},{"de":"Im Ballett tanzt man oft auf den Spitzen.","en":"In ballet one often dances on points.","ru":"В балете часто танцуют на пуантах.","vi":"Trong múa ba lê bạn thường nhảy theo điểm.","fa":"در باله اغلب روی پوینت می رقصید."},{"de":"Sie balancierte mühelos auf der Spitze.","en":"She balanced effortlessly on her toes.","ru":"Она без усилий балансировала на носках.","vi":"Cô ấy giữ thăng bằng dễ dàng ở phía trên.","fa":"او بدون زحمت در بالا تعادل برقرار کرد."}]},{"word":"der Sport","en":"sport","ru":"спорт","vi":"môn thể thao","fa":"ورزش","examples":[{"de":"Er treibt jeden Tag Sport.","en":"He does sports every day.","ru":"Он занимается спортом каждый день.","vi":"Anh ấy chơi thể thao mỗi ngày.","fa":"او هر روز ورزش می کند."},{"de":"Welchen Sport magst du am liebsten?","en":"Which sport do you like best?","ru":"Какой вид спорта тебе нравится больше всего?","vi":"Bạn thích môn thể thao nào nhất?","fa":"کدام ورزش را بیشتر دوست دارید؟"}]},{"word":"die Sportart","en":"type of sport, sport","ru":"вид спорта","vi":"môn thể thao","fa":"ورزش","examples":[{"de":"Schwimmen ist meine Lieblingssportart.","en":"Swimming is my favourite sport.","ru":"Плавание — мой любимый вид спорта.","vi":"Bơi lội là môn thể thao yêu thích của tôi.","fa":"شنا ورزش مورد علاقه من است."},{"de":"Welche Sportart treibst du am liebsten?","en":"Which sport do you most like to do?","ru":"Каким видом спорта ты больше всего любишь заниматься?","vi":"Bạn thích môn thể thao nào nhất?","fa":"از چه ورزشی بیشتر لذت می برید؟"},{"de":"Fußball ist in Deutschland die beliebteste Sportart.","en":"Football is the most popular sport in Germany.","ru":"Футбол — самый популярный вид спорта в Германии.","vi":"Bóng đá là môn thể thao phổ biến nhất ở Đức.","fa":"فوتبال محبوب ترین ورزش در آلمان است."}]},{"word":"der Sportler","en":"athlete, sportsman","ru":"спортсмен","vi":"vận động viên","fa":"ورزشکار","examples":[{"de":"Der Sportler trainiert jeden Morgen vor der Arbeit.","en":"The athlete trains every morning before work.","ru":"Спортсмен тренируется каждое утро перед работой.","vi":"Vận động viên tập luyện vào mỗi buổi sáng trước khi làm việc.","fa":"ورزشکار هر روز صبح قبل از کار تمرین می کند."},{"de":"Ein guter Sportler muss sich gesund ernähren.","en":"A good athlete has to eat healthily.","ru":"Хороший спортсмен должен питаться правильно.","vi":"Một vận động viên giỏi phải ăn uống lành mạnh.","fa":"یک ورزشکار خوب باید سالم غذا بخورد."},{"de":"Der Sportler gewann eine Goldmedaille.","en":"The athlete won a gold medal.","ru":"Спортсмен выиграл золотую медаль.","vi":"Vận động viên này đã giành được huy chương vàng.","fa":"این ورزشکار موفق به کسب مدال طلا شد."}]},{"word":"die Sportlerin","en":"athlete, sportswoman","ru":"спортсменка","vi":"vận động viên","fa":"ورزشکار","examples":[{"de":"Die Sportlerin hat einen neuen Rekord aufgestellt.","en":"The athlete set a new record.","ru":"Спортсменка установила новый рекорд.","vi":"Vận động viên này đã lập kỷ lục mới.","fa":"این ورزشکار رکورد جدیدی به ثبت رسانده است."},{"de":"Sie ist eine der besten Sportlerinnen des Landes.","en":"She is one of the best athletes in the country.","ru":"Она одна из лучших спортсменок в стране.","vi":"Cô là một trong những vận động viên giỏi nhất đất nước.","fa":"او یکی از بهترین ورزشکاران کشور است."},{"de":"Die junge Sportlerin trainiert für die Olympischen Spiele.","en":"The young athlete is training for the Olympic Games.","ru":"Молодая спортсменка готовится к Олимпийским играм.","vi":"Vận động viên trẻ đang tập luyện cho Thế vận hội Olympic.","fa":"این ورزشکار جوان برای بازی های المپیک تمرین می کند."}]},{"word":"die Sportsendung","en":"sports programme (TV/radio)","ru":"спортивная передача (теле-/радио)","vi":"chương trình thể thao","fa":"نمایش ورزشی","examples":[{"de":"Am Samstagabend schaue ich gern eine Sportsendung.","en":"On Saturday evening I like to watch a sports programme.","ru":"В субботу вечером я люблю смотреть спортивную передачу.","vi":"Vào tối thứ bảy tôi thích xem một chương trình thể thao.","fa":"شنبه عصرها دوست دارم یک برنامه ورزشی ببینم."},{"de":"In der Sportsendung wurden alle Ergebnisse gezeigt.","en":"In the sports programme all the results were shown.","ru":"В спортивной передаче показали все результаты.","vi":"Tất cả các kết quả đã được hiển thị trong chương trình thể thao.","fa":"تمام نتایج در پخش ورزشی نشان داده شد."},{"de":"Mein Vater verpasst keine einzige Sportsendung.","en":"My father doesn't miss a single sports programme.","ru":"Мой отец не пропускает ни одной спортивной передачи.","vi":"Cha tôi không bỏ lỡ một chương trình thể thao nào.","fa":"پدرم حتی یک برنامه ورزشی را از دست نمی دهد."}]},{"word":"die Sprache","en":"language","ru":"язык (речь)","vi":"ngôn ngữ","fa":"زبان","examples":[{"de":"Sie spricht drei Sprachen fließend.","en":"She speaks three languages fluently.","ru":"Она свободно говорит на трёх языках.","vi":"Cô ấy nói trôi chảy ba thứ tiếng.","fa":"او سه زبان را روان صحبت می کند."},{"de":"Deutsch ist eine schwierige Sprache für viele Anfänger.","en":"German is a difficult language for many beginners.","ru":"Немецкий — трудный язык для многих начинающих.","vi":"Tiếng Đức là một ngôn ngữ khó đối với nhiều người mới bắt đầu.","fa":"آلمانی برای بسیاری از مبتدیان زبان دشواری است."}]},{"word":"der Sprachkurs","en":"a language course","ru":"языковой курс","vi":"khóa học ngôn ngữ","fa":"the language course","examples":[{"de":"Wir haben einen Sprachkurs in Köln gewonnen.","en":"We have won a language course in Cologne.","ru":"Мы выиграли языковой курс в Кёльне.","vi":"Chúng tôi đã giành được một khóa học ngôn ngữ ở Cologne.","fa":"یک دوره زبان در کلن بردیم."},{"de":"Im Sommer besuche ich einen Sprachkurs in Wien.","en":"In the summer I'm attending a language course in Vienna.","ru":"Летом я хожу на языковой курс в Вене.","vi":"Vào mùa hè, tôi đang tham gia một khóa học ngôn ngữ ở Vienna.","fa":"در تابستان در یک دوره زبان در وین شرکت می کنم."},{"de":"Der Sprachkurs findet jeden Dienstag und Donnerstag statt.","en":"The language course takes place every Tuesday and Thursday.","ru":"Языковой курс проходит каждый вторник и четверг.","vi":"Khóa học ngôn ngữ diễn ra vào thứ Ba và thứ Năm hàng tuần.","fa":"دوره زبان هر سه شنبه و پنجشنبه برگزار می شود."}]},{"word":"sprechen","en":"to speak","ru":"говорить","vi":"nói","fa":"صحبت کنید","examples":[{"de":"Kannst du bitte langsamer sprechen?","en":"Can you please speak more slowly?","ru":"Можешь, пожалуйста, говорить медленнее?","vi":"Bạn có thể vui lòng nói chậm hơn được không?","fa":"میشه لطفا آهسته تر صحبت کنید؟"},{"de":"Wir müssen dringend über das Problem sprechen.","en":"We urgently need to talk about the problem.","ru":"Нам срочно нужно поговорить об этой проблеме.","vi":"Chúng tôi cần khẩn trương nói về vấn đề này.","fa":"ما باید فوراً در مورد مشکل صحبت کنیم."}]},{"word":"die Sprechstunde","en":"office hours; consultation hours","ru":"приёмные часы; часы приёма","vi":"giờ tư vấn","fa":"ساعت مشاوره","examples":[{"de":"Der Professor hat mittwochs Sprechstunde.","en":"The professor has office hours on Wednesdays.","ru":"У профессора приёмные часы по средам.","vi":"Giáo sư có giờ hành chính vào thứ Tư.","fa":"استاد چهارشنبه ها ساعت اداری دارد."},{"de":"Die Sprechstunde des Arztes beginnt um neun Uhr.","en":"The doctor's consultation hours begin at nine o'clock.","ru":"Часы приёма врача начинаются в девять часов.","vi":"Cuộc tư vấn của bác sĩ bắt đầu lúc chín giờ.","fa":"مشاوره دکتر از ساعت نه شروع می شود."}]},{"word":"springen","en":"to jump","ru":"прыгать","vi":"nhảy","fa":"پرش","examples":[{"de":"Die Kinder springen fröhlich über die Pfützen.","en":"The children happily jump over the puddles.","ru":"Дети весело прыгают через лужи.","vi":"Lũ trẻ vui vẻ nhảy qua vũng nước.","fa":"بچه ها با خوشحالی از روی گودال ها می پرند."},{"de":"Er ist ins Wasser gesprungen.","en":"He jumped into the water.","ru":"Он прыгнул в воду.","vi":"Anh ta nhảy xuống nước.","fa":"پرید توی آب."}]},{"word":"die Spritze","en":"injection; syringe","ru":"укол; шприц","vi":"ống tiêm","fa":"سرنگ","examples":[{"de":"Der Arzt gibt dem Patienten eine Spritze.","en":"The doctor gives the patient an injection.","ru":"Врач делает пациенту укол.","vi":"Bác sĩ tiêm thuốc cho bệnh nhân.","fa":"پزشک به بیمار تزریق می کند."},{"de":"Vor der Reise brauchte sie eine Spritze gegen Gelbfieber.","en":"Before the trip she needed a shot against yellow fever.","ru":"Перед поездкой ей понадобилась прививка от жёлтой лихорадки.","vi":"Trước chuyến đi, cô cần tiêm một mũi chống sốt vàng da.","fa":"قبل از سفر او برای تب زرد نیاز به تزریق داشت."}]},{"word":"spritzig","en":"zesty, fizzy, lively (of a drink)","ru":"живой, искристый, лёгкий (о напитке)","vi":"lấp lánh","fa":"درخشان","examples":[{"de":"Dieser Weißwein ist schön spritzig und leicht.","en":"This white wine is nicely zesty and light.","ru":"Это белое вино приятно искристое и лёгкое.","vi":"Loại rượu vang trắng này rất đẹp, lấp lánh và nhẹ nhàng.","fa":"این شراب سفید خوب و درخشان و سبک است."},{"de":"Die Schorle schmeckt frisch und spritzig.","en":"The spritzer tastes fresh and zesty.","ru":"Шорле на вкус свежий и искристый.","vi":"Spritzer có vị tươi và thơm.","fa":"طعم اسپریتزر تازه و تلخ است."},{"de":"Ein spritziges Getränk passt zum Sommer.","en":"A fizzy drink suits the summer.","ru":"Искристый напиток подходит к лету.","vi":"Một thức uống lấp lánh phù hợp với mùa hè.","fa":"یک نوشیدنی گازدار مناسب تابستان است."}]},{"word":"der Sprung","en":"jump, leap","ru":"прыжок","vi":"bước nhảy","fa":"پرش","examples":[{"de":"Der Sprung des Tänzers wirkte fast schwerelos.","en":"The dancer's jump looked almost weightless.","ru":"Прыжок танцора выглядел почти невесомым.","vi":"Cú nhảy của vũ công dường như gần như không trọng lượng.","fa":"پرش رقصنده تقریباً بی وزن به نظر می رسید."},{"de":"Im Ballett gibt es viele verschiedene Sprünge.","en":"In ballet there are many different jumps.","ru":"В балете есть много разных прыжков.","vi":"Có rất nhiều bước nhảy khác nhau trong múa ba lê.","fa":"پرش های مختلف زیادی در باله وجود دارد."},{"de":"Für diesen Sprung braucht man starke Beine.","en":"You need strong legs for this jump.","ru":"Для этого прыжка нужны сильные ноги.","vi":"Bạn cần đôi chân khỏe mạnh cho bước nhảy này.","fa":"برای این پرش به پاهای قوی نیاز دارید."}]},{"word":"das Spülbecken","en":"sink","ru":"мойка, раковина (кухонная)","vi":"bồn rửa","fa":"سینک ظرفشویی","examples":[{"de":"Im Spülbecken stapelt sich das schmutzige Geschirr.","en":"The dirty dishes are piling up in the sink.","ru":"В мойке громоздится грязная посуда.","vi":"Bát đĩa bẩn chất đầy trong bồn rửa.","fa":"ظرف های کثیف در سینک انباشته می شوند."},{"de":"Lass kein Wasser im Spülbecken stehen.","en":"Don't leave any water standing in the sink.","ru":"Не оставляй воду в мойке.","vi":"Đừng để nước trong bồn rửa.","fa":"آب را در سینک نگذارید."},{"de":"Das Spülbecken aus Edelstahl ist leicht zu reinigen.","en":"The stainless steel sink is easy to clean.","ru":"Мойку из нержавеющей стали легко чистить.","vi":"Bồn rửa bằng thép không gỉ rất dễ dàng để làm sạch.","fa":"سینک استیل ضد زنگ به راحتی تمیز می شود."}]},{"word":"spülen","en":"to rinse; to wash (dishes)","ru":"мыть (посуду); полоскать","vi":"rửa sạch","fa":"آبکشی کنید","examples":[{"de":"Nach dem Essen muss noch das Geschirr gespült werden.","en":"After eating, the dishes still need to be washed.","ru":"После еды нужно ещё помыть посуду.","vi":"Ăn xong vẫn phải rửa bát.","fa":"پس از صرف غذا، ظروف هنوز باید شسته شوند."},{"de":"Sie spült die Gläser mit warmem Wasser.","en":"She rinses the glasses with warm water.","ru":"Она моет стаканы тёплой водой.","vi":"Cô rửa kính bằng nước ấm.","fa":"لیوان‌ها را با آب گرم می‌شوید."}]},{"word":"die Spur","en":"trace; track; lane (road)","ru":"след; полоса (движения)","vi":"dấu vết; làn đường","fa":"رد؛ ردپا","examples":[{"de":"Die Polizei fand keine Spur von dem Dieb.","en":"The police found no trace of the thief.","ru":"Полиция не нашла и следа вора.","vi":"Cảnh sát không tìm thấy dấu vết của tên trộm.","fa":"پلیس هیچ اثری از دزد پیدا نکرد."},{"de":"Bleib auf deiner Spur, bis die Ausfahrt kommt.","en":"Stay in your lane until the exit comes.","ru":"Оставайся на своей полосе, пока не появится съезд.","vi":"Đi trong làn đường của bạn cho đến khi có lối ra.","fa":"تا زمانی که خروجی بیاید در لاین خود بمانید."}]},{"word":"spüren","en":"to feel; to sense","ru":"чувствовать; ощущать","vi":"cảm thấy","fa":"احساس کنید","examples":[{"de":"Ich spüre, dass etwas nicht stimmt.","en":"I sense that something is wrong.","ru":"Я чувствую, что что-то не так.","vi":"Tôi cảm thấy có điều gì đó không ổn.","fa":"احساس می کنم چیزی اشتباه است."},{"de":"Sie spürte den kalten Wind im Gesicht.","en":"She felt the cold wind on her face.","ru":"Она почувствовала холодный ветер на лице.","vi":"Cô cảm thấy gió lạnh phả vào mặt.","fa":"باد سرد را روی صورتش احساس کرد."}]},{"word":"das Stadion","en":"stadium","ru":"стадион","vi":"sân vận động","fa":"استادیوم","examples":[{"de":"Am Samstag treffen wir uns im Stadion zum Fußballspiel.","en":"On Saturday we're meeting at the stadium for the football match.","ru":"В субботу мы встречаемся на стадионе на футбольный матч.","vi":"Vào thứ bảy, chúng tôi gặp nhau ở sân vận động để xem trận bóng đá.","fa":"شنبه برای بازی فوتبال در استادیوم همدیگر را ملاقات می کنیم."},{"de":"Das neue Stadion bietet Platz für 50.000 Zuschauer.","en":"The new stadium holds 50,000 spectators.","ru":"Новый стадион вмещает 50 000 зрителей.","vi":"Sân vận động mới có sức chứa 50.000 khán giả.","fa":"ورزشگاه جدید فضایی برای 50000 تماشاگر دارد."}]},{"word":"die Stadt","en":"city; town","ru":"город","vi":"thành phố","fa":"شهر","examples":[{"de":"Berlin ist die Hauptstadt von Deutschland.","en":"Berlin is the capital city of Germany.","ru":"Берлин — столица Германии.","vi":"Berlin là thủ đô của Đức.","fa":"برلین پایتخت آلمان است."},{"de":"Wir fahren morgen in die Stadt, um einzukaufen.","en":"We're going into town tomorrow to shop.","ru":"Завтра мы едем в город за покупками.","vi":"Ngày mai chúng ta sẽ vào thị trấn để mua sắm.","fa":"فردا میریم شهر تا خرید کنیم."}]},{"word":"die Städtereise","en":"city break, city trip","ru":"поездка в город, городской тур","vi":"chuyến đi thành phố","fa":"سفر شهری","examples":[{"de":"Am Wochenende machen wir eine Städtereise nach Prag.","en":"At the weekend we're taking a city break to Prague.","ru":"На выходные мы едем в Прагу на городскую экскурсию.","vi":"Vào cuối tuần chúng tôi sẽ đi du lịch thành phố Praha.","fa":"آخر هفته به یک سفر شهری به پراگ می رویم."},{"de":"Eine Städtereise ist ideal für ein langes Wochenende.","en":"A city break is ideal for a long weekend.","ru":"Поездка в город идеальна для длинных выходных.","vi":"Một chuyến đi thành phố là lý tưởng cho một ngày cuối tuần dài.","fa":"یک سفر شهری برای یک آخر هفته طولانی ایده آل است."},{"de":"Bei einer Städtereise besucht man oft viele Museen.","en":"On a city break you often visit lots of museums.","ru":"В поездке по городу часто посещают много музеев.","vi":"Trong chuyến du lịch thành phố bạn thường ghé thăm nhiều viện bảo tàng.","fa":"در طول یک سفر شهری اغلب از موزه های بسیاری بازدید می کنید."}]},{"word":"städtisch","en":"urban; municipal","ru":"городской, муниципальный","vi":"đô thị","fa":"شهری","examples":[{"de":"Das städtische Krankenhaus liegt im Zentrum.","en":"The municipal hospital is in the centre.","ru":"Городская больница находится в центре.","vi":"Bệnh viện thành phố nằm ở trung tâm.","fa":"بیمارستان شهرداری در مرکز قرار دارد."},{"de":"Sie arbeitet im städtischen Kindergarten.","en":"She works at the municipal nursery.","ru":"Она работает в муниципальном детском саду.","vi":"Cô làm việc ở trường mẫu giáo thành phố.","fa":"او در مهد کودک شهرداری کار می کند."},{"de":"Das städtische Leben gefällt mir besser als das auf dem Land.","en":"I like urban life better than country life.","ru":"Городская жизнь мне нравится больше, чем деревенская.","vi":"Tôi thích cuộc sống thành thị hơn cuộc sống nông thôn.","fa":"من زندگی شهری را بیشتر از زندگی روستایی دوست دارم."}]},{"word":"der Stadtplan","en":"city map","ru":"план города, карта города","vi":"bản đồ thành phố","fa":"نقشه شهر","examples":[{"de":"Auf dem Stadtplan finde ich unser Hotel nicht.","en":"I can't find our hotel on the city map.","ru":"Я не могу найти наш отель на плане города.","vi":"Tôi không thể tìm thấy khách sạn của chúng tôi trên bản đồ thành phố.","fa":"من نمی توانم هتلمان را روی نقشه شهر پیدا کنم."},{"de":"Im Hotel bekommt man einen kostenlosen Stadtplan.","en":"At the hotel you get a free city map.","ru":"В отеле можно получить бесплатный план города.","vi":"Bạn nhận được một bản đồ thành phố miễn phí tại khách sạn.","fa":"شما یک نقشه شهر رایگان در هتل دریافت می کنید."},{"de":"Mit dem Stadtplan haben wir uns trotzdem verlaufen.","en":"Even with the city map we got lost.","ru":"Даже с планом города мы всё равно заблудились.","vi":"Chúng tôi vẫn bị lạc với bản đồ thành phố.","fa":"ما هنوز با نقشه شهر گم شدیم."}]},{"word":"stammen","en":"to come from; to originate","ru":"происходить (из/от)","vi":"bắt nguồn","fa":"سرچشمه می گیرند","examples":[{"de":"Meine Familie stammt ursprünglich aus Italien.","en":"My family originally comes from Italy.","ru":"Моя семья родом из Италии.","vi":"Gia đình tôi có nguồn gốc từ Ý.","fa":"خانواده من اصالتا ایتالیایی هستند."},{"de":"Dieses Wort stammt aus dem Lateinischen.","en":"This word comes from Latin.","ru":"Это слово происходит из латыни.","vi":"Từ này xuất phát từ tiếng Latin.","fa":"این کلمه از لاتین آمده است."}]},{"word":"der Stammtisch","en":"regulars' table, regulars' meet-up","ru":"стол для завсегдатаев; постоянная компания за таким столом","vi":"bảng của người thường xuyên","fa":"میز معمولی ها","examples":[{"de":"Jeden Freitag treffen wir uns am Stammtisch.","en":"Every Friday we meet at the regulars' table.","ru":"Каждую пятницу мы встречаемся за столом завсегдатаев.","vi":"Thứ Sáu hàng tuần chúng tôi gặp nhau tại bàn của những người thường xuyên.","fa":"هر جمعه سر میز معمولی همدیگر را می بینیم."},{"de":"Der Stammtisch ist seit Jahren reserviert.","en":"The regulars' table has been reserved for years.","ru":"Стол для завсегдатаев зарезервирован уже много лет.","vi":"Bàn dành cho khách thường xuyên đã được đặt trước trong nhiều năm.","fa":"میز معمولی ها سالهاست که رزرو شده است."},{"de":"Am Stammtisch wird über Politik diskutiert.","en":"At the regulars' table they discuss politics.","ru":"За столом завсегдатаев обсуждают политику.","vi":"Chính trị được thảo luận tại bàn của chính quyền.","fa":"بحث سیاست سر میز همیشگی هاست."}]},{"word":"ständig","en":"constantly; continually","ru":"постоянно","vi":"liên tục","fa":"دائما","examples":[{"de":"Er beschwert sich ständig über das Wetter.","en":"He constantly complains about the weather.","ru":"Он постоянно жалуется на погоду.","vi":"Anh ấy liên tục phàn nàn về thời tiết.","fa":"مدام از آب و هوا شاکی است."},{"de":"Meine Schwester ruft mich ständig an.","en":"My sister calls me constantly.","ru":"Моя сестра постоянно мне звонит.","vi":"Chị tôi gọi điện cho tôi suốt.","fa":"خواهرم مدام با من تماس می گیرد."}]},{"word":"der Standpunkt","en":"point of view; standpoint","ru":"точка зрения","vi":"quan điểm","fa":"نقطه نظر","examples":[{"de":"Von meinem Standpunkt aus ist das keine gute Idee.","en":"From my point of view, that's not a good idea.","ru":"С моей точки зрения, это не очень хорошая идея.","vi":"Theo quan điểm của tôi, đây không phải là một ý tưởng hay.","fa":"از دیدگاه من، این ایده خوبی نیست."},{"de":"Er vertritt in dieser Frage einen klaren Standpunkt.","en":"He holds a clear position on this issue.","ru":"У него чёткая позиция по этому вопросу.","vi":"Ông có quan điểm rõ ràng về vấn đề này.","fa":"او موضع روشنی در این مورد دارد."}]},{"word":"der Star","en":"star (celebrity)","ru":"звезда (знаменитость)","vi":"ngôi sao","fa":"ستاره","examples":[{"de":"Der Schauspieler ist ein großer Star in Hollywood.","en":"The actor is a big star in Hollywood.","ru":"Этот актёр — большая звезда Голливуда.","vi":"Nam diễn viên là một ngôi sao lớn ở Hollywood.","fa":"این بازیگر یک ستاره بزرگ در هالیوود است."},{"de":"Viele Fans warteten vor dem Konzert auf ihren Star.","en":"Many fans waited outside the concert for their star.","ru":"Многие фанаты ждали перед концертом свою звезду.","vi":"Người hâm mộ Viele chiến đấu với Konzert auf ihren Star.","fa":"بسیاری از هواداران قبل از کنسرت منتظر ستاره خود بودند."}]},{"word":"stark","en":"strong","ru":"сильный","vi":"mạnh mẽ","fa":"قوی","examples":[{"de":"Er ist körperlich sehr stark.","en":"He is physically very strong.","ru":"Он физически очень сильный.","vi":"He is physically very strong.","fa":"او از نظر بدنی بسیار قوی است."},{"de":"Der Kaffee heute Morgen war zu stark für mich.","en":"The coffee this morning was too strong for me.","ru":"Кофе сегодня утром был для меня слишком крепким.","vi":"Cà phê sáng nay quá mạnh đối với tôi.","fa":"قهوه امروز صبح برای من خیلی قوی بود."}]},{"word":"die Stärke","en":"strength, strong point","ru":"сила; сильная сторона","vi":"sức mạnh","fa":"قدرت","examples":[{"de":"Geduld ist eine ihrer größten Stärken.","en":"Patience is one of her greatest strengths.","ru":"Терпение — одна из её самых сильных сторон.","vi":"Kiên nhẫn là một trong những điểm mạnh lớn nhất của cô ấy.","fa":"صبر یکی از بزرگترین نقاط قوت اوست."},{"de":"Man sollte seine Stärken und Schwächen kennen.","en":"You should know your strengths and weaknesses.","ru":"Тебе следует знать свои сильные и слабые стороны.","vi":"Bạn nên biết điểm mạnh và điểm yếu của mình.","fa":"شما باید نقاط قوت و ضعف خود را بشناسید."},{"de":"Die Stärke des Windes nahm immer mehr zu.","en":"The strength of the wind kept increasing.","ru":"Сила ветра всё возрастала.","vi":"Sức mạnh của gió ngày càng tăng lên.","fa":"شدت باد بیشتر و بیشتر می شد."}]},{"word":"der Start","en":"start, take-off","ru":"старт; взлёт","vi":"sự khởi đầu","fa":"شروع","examples":[{"de":"Der Start des Rennens war pünktlich um zwölf Uhr.","en":"The start of the race was punctually at twelve o'clock.","ru":"Старт гонки был ровно в двенадцать часов.","vi":"Cuộc đua bắt đầu đúng lúc mười hai giờ.","fa":"مسابقه به سرعت در ساعت دوازده شروع شد."},{"de":"Vor dem Start des Flugzeugs muss man sich anschnallen.","en":"Before the plane's take-off you have to fasten your seatbelt.","ru":"Перед взлётом самолёта нужно пристегнуть ремень.","vi":"Bạn phải thắt dây an toàn trước khi máy bay cất cánh.","fa":"قبل از بلند شدن هواپیما باید کمربند ایمنی خود را ببندید."},{"de":"Das neue Projekt hatte einen schwierigen Start.","en":"The new project had a difficult start.","ru":"У нового проекта был трудный старт.","vi":"Dự án mới đã có một khởi đầu khó khăn.","fa":"پروژه جدید شروع سختی داشت."}]},{"word":"starten","en":"to start; to launch; to take off","ru":"стартовать; запускать(ся)","vi":"bắt đầu","fa":"شروع کنید","examples":[{"de":"Das Flugzeug startet um sieben Uhr.","en":"The plane takes off at seven o'clock.","ru":"Самолёт вылетает в семь часов.","vi":"Máy bay cất cánh lúc bảy giờ.","fa":"هواپیما ساعت هفت بلند می شود."},{"de":"Wir starten das Projekt nächste Woche.","en":"We're launching the project next week.","ru":"Мы запускаем проект на следующей неделе.","vi":"Chúng tôi bắt đầu dự án vào tuần tới.","fa":"هفته آینده پروژه را شروع می کنیم."}]},{"word":"die Station","en":"station (hospital ward, transit stop)","ru":"станция; отделение (в больнице)","vi":"nhà ga","fa":"ایستگاه","examples":[{"de":"Mein Onkel liegt auf der Station im dritten Stock.","en":"My uncle is on the ward on the third floor.","ru":"Мой дядя лежит в отделении на третьем этаже.","vi":"Chú tôi ở phòng bệnh trên tầng ba.","fa":"عمویم در بند طبقه سوم است."},{"de":"An der nächsten Station müssen wir aussteigen.","en":"We have to get off at the next stop.","ru":"На следующей остановке нам нужно выходить.","vi":"Chúng ta phải xuống ở ga tiếp theo.","fa":"باید در ایستگاه بعدی پیاده شویم."}]},{"word":"die Statistik","en":"statistics","ru":"статистика","vi":"số liệu thống kê","fa":"آمار","examples":[{"de":"Laut Statistik sinkt die Zahl der Raucher.","en":"According to statistics, the number of smokers is declining.","ru":"Согласно статистике, число курящих снижается.","vi":"Theo thống kê, số lượng người hút thuốc đang giảm dần.","fa":"طبق آمار، تعداد افراد سیگاری در حال کاهش است."},{"de":"Sie muss für ihr Studium ein Fach in Statistik belegen.","en":"She has to take a statistics course for her studies.","ru":"Ей нужно пройти курс статистики в рамках учёбы.","vi":"Cô ấy phải học một môn về thống kê để học.","fa":"او باید برای تحصیلاتش موضوعی را در آمار بگذراند."}]},{"word":"statistisch","en":"statistical","ru":"статистический","vi":"thống kê","fa":"آماری","examples":[{"de":"Statistisch gesehen leben Frauen länger als Männer.","en":"Statistically speaking, women live longer than men.","ru":"Статистически женщины живут дольше мужчин.","vi":"Theo thống kê, phụ nữ sống lâu hơn nam giới.","fa":"از نظر آماری، زنان بیشتر از مردان عمر می کنند."},{"de":"Die statistischen Daten zeigen einen klaren Trend.","en":"The statistical data show a clear trend.","ru":"Статистические данные показывают чёткую тенденцию.","vi":"Các dữ liệu thống kê cho thấy một xu hướng rõ ràng.","fa":"داده های آماری روند واضحی را نشان می دهد."},{"de":"Das ist nur ein statistischer Durchschnitt.","en":"That is only a statistical average.","ru":"Это лишь статистическое среднее.","vi":"Đây chỉ là con số trung bình thống kê.","fa":"این فقط یک میانگین آماری است."}]},{"word":"statt","en":"instead of","ru":"вместо","vi":"thay vào đó","fa":"در عوض","examples":[{"de":"Statt Kaffee trinke ich lieber Tee.","en":"Instead of coffee, I prefer to drink tea.","ru":"Вместо кофе я предпочитаю пить чай.","vi":"Tôi thích uống trà hơn là cà phê.","fa":"من ترجیح می دهم به جای قهوه چای بنوشم."},{"de":"Er kam statt seines Bruders zur Feier.","en":"He came to the celebration instead of his brother.","ru":"Он пришёл на праздник вместо своего брата.","vi":"Anh ấy đến dự lễ kỷ niệm thay vì anh trai mình.","fa":"او به جای برادرش به جشن آمد."}]},{"word":"stattfinden","en":"to take place","ru":"происходить; состояться","vi":"diễn ra","fa":"برگزار شود","examples":[{"de":"Die Konferenz findet nächsten Monat statt.","en":"The conference takes place next month.","ru":"Конференция состоится в следующем месяце.","vi":"Die Konferenz đã tìm thấy Monat statt.","fa":"این کنفرانس در ماه آینده برگزار می شود."},{"de":"Wegen des Regens fand das Fest nicht im Freien statt.","en":"Because of the rain, the festival did not take place outdoors.","ru":"Из-за дождя праздник не проходил на улице.","vi":"Vì trời mưa nên lễ hội không được tổ chức ngoài trời.","fa":"به دلیل بارندگی، جشنواره در فضای باز برگزار نشد."}]},{"word":"der Stau","en":"traffic jam","ru":"пробка (на дороге)","vi":"ùn tắc giao thông","fa":"ترافیک","examples":[{"de":"Wir standen zwei Stunden im Stau.","en":"We were stuck in a traffic jam for two hours.","ru":"Мы простояли в пробке два часа.","vi":"Chúng tôi bị kẹt xe suốt hai tiếng đồng hồ.","fa":"دو ساعت در ترافیک گیر کرده بودیم."},{"de":"Auf der Autobahn gibt es heute einen langen Stau.","en":"There's a long traffic jam on the highway today.","ru":"Сегодня на автобане длинная пробка.","vi":"Hôm nay đường cao tốc bị ùn tắc kéo dài.","fa":"امروز یک ترافیک طولانی در بزرگراه وجود دارد."}]},{"word":"der Staub","en":"dust","ru":"пыль","vi":"bụi","fa":"گرد و غبار","examples":[{"de":"Auf dem Regal liegt viel Staub.","en":"There's a lot of dust on the shelf.","ru":"На полке много пыли.","vi":"Có rất nhiều bụi trên kệ.","fa":"گرد و غبار زیادی روی قفسه وجود دارد."},{"de":"Sie wischt jeden Tag den Staub von den Möbeln.","en":"She wipes the dust off the furniture every day.","ru":"Она каждый день вытирает пыль с мебели.","vi":"She wipes the dust off the furniture every day.","fa":"او هر روز گرد و غبار مبلمان را پاک می کند."}]},{"word":"Staub saugen","en":"to vacuum, to hoover","ru":"пылесосить","vi":"chân không","fa":"وکیوم","examples":[{"de":"Am Samstag muss ich die ganze Wohnung Staub saugen.","en":"On Saturday I have to vacuum the whole flat.","ru":"В субботу мне нужно пропылесосить всю квартиру.","vi":"Vào thứ bảy tôi phải hút bụi toàn bộ căn hộ.","fa":"شنبه باید کل آپارتمان را جاروبرقی بکشم."},{"de":"Kannst du bitte im Wohnzimmer Staub saugen?","en":"Could you please vacuum in the living room?","ru":"Не мог бы ты пропылесосить в гостиной?","vi":"Bạn có thể vui lòng hút bụi phòng khách được không?","fa":"آیا می توانید اتاق نشیمن را جاروبرقی بکشید؟"},{"de":"Bevor die Gäste kommen, sauge ich noch schnell Staub.","en":"Before the guests arrive, I'll quickly do some vacuuming.","ru":"Перед приходом гостей я быстро пропылесошу.","vi":"Trước khi khách tới, tôi nhanh chóng hút bụi phòng.","fa":"قبل از اینکه مهمان ها بیایند، سریع اتاق را جاروبرقی می کشم."}]},{"word":"staubsaugen","en":"to vacuum","ru":"пылесосить","vi":"chân không","fa":"خلاء","examples":[{"de":"Am Samstag muss ich die ganze Wohnung staubsaugen.","en":"On Saturday I have to vacuum the whole apartment.","ru":"В субботу мне нужно пропылесосить всю квартиру.","vi":"Vào thứ bảy tôi phải hút bụi toàn bộ căn hộ.","fa":"شنبه باید کل آپارتمان را جاروبرقی بکشم."},{"de":"Er saugt jeden Tag Staub im Wohnzimmer.","en":"He vacuums the living room every day.","ru":"Он каждый день пылесосит гостиную.","vi":"Anh ấy hút bụi phòng khách mỗi ngày.","fa":"او هر روز اتاق نشیمن را جاروبرقی می کشد."}]},{"word":"stechen","en":"to sting; to prick; to stab","ru":"колоть; жалить","vi":"đốt","fa":"نیش زدن","examples":[{"de":"Eine Biene hat mich in den Arm gestochen.","en":"A bee stung me on the arm.","ru":"Пчела ужалила меня в руку.","vi":"Một con ong chích vào tay tôi.","fa":"زنبوری روی بازویم نیش زد."},{"de":"Pass auf, die Rosen stechen!","en":"Watch out, the roses prick!","ru":"Осторожно, розы колются!","vi":"Coi chừng, hoa hồng chích!","fa":"مراقب باشید، گل رز نیش می زند!"}]},{"word":"die Steckdose","en":"electrical socket; outlet","ru":"розетка","vi":"ổ cắm","fa":"سوکت","examples":[{"de":"Die Lampe passt nicht in diese Steckdose.","en":"The lamp doesn't fit this socket.","ru":"Лампа не подходит к этой розетке.","vi":"Đèn không vừa với ổ cắm này.","fa":"لامپ در این سوکت جا نمی شود."},{"de":"In jedem Zimmer gibt es mindestens zwei Steckdosen.","en":"There are at least two outlets in every room.","ru":"В каждой комнате есть как минимум две розетки.","vi":"Có ít nhất hai ổ cắm điện trong mỗi phòng.","fa":"در هر اتاق حداقل دو پریز برق وجود دارد."}]},{"word":"stecken","en":"to put; to stick; to be (somewhere)","ru":"класть; втыкать; находиться","vi":"bị mắc kẹt","fa":"گیر کرده","examples":[{"de":"Sie steckt den Schlüssel ins Schloss.","en":"She puts the key in the lock.","ru":"Она вставляет ключ в замок.","vi":"Cô tra chìa khóa vào ổ khóa.","fa":"او کلید را در قفل می گذارد."},{"de":"Wo steckst du denn die ganze Zeit?","en":"Where have you been all this time?","ru":"Где ты вообще всё это время пропадал?","vi":"Bạn đã ở đâu suốt thời gian qua?","fa":"این همه مدت کجا بودی؟"}]},{"word":"der Stecker","en":"plug (electrical)","ru":"вилка (электрическая), штепсель","vi":"phích cắm","fa":"دوشاخه","examples":[{"de":"Zieh den Stecker aus der Steckdose, bevor du das Gerät reparierst.","en":"Pull the plug out of the socket before repairing the device.","ru":"Вынь вилку из розетки, прежде чем ремонтировать прибор.","vi":"Rút phích cắm thiết bị trước khi sửa chữa thiết bị.","fa":"قبل از تعمیر دستگاه، دستگاه را از برق بکشید."},{"de":"Der Stecker meines Ladegeräts ist kaputt.","en":"The plug of my charger is broken.","ru":"Вилка моего зарядного устройства сломана.","vi":"Ổ cắm trên bộ sạc của tôi bị hỏng.","fa":"دوشاخه شارژر من خرابه"}]},{"word":"stehen","en":"to stand","ru":"стоять","vi":"đứng","fa":"ایستادن","examples":[{"de":"Die Flasche steht auf dem Tisch.","en":"The bottle is standing on the table.","ru":"Бутылка стоит на столе.","vi":"Cái chai ở trên bàn.","fa":"بطری روی میز است."},{"de":"Wir mussten eine Stunde in der Schlange stehen.","en":"We had to stand in line for an hour.","ru":"Нам пришлось стоять в очереди целый час.","vi":"Chúng tôi phải xếp hàng chờ cả tiếng đồng hồ.","fa":"مجبور شدیم یک ساعت در صف بمانیم."}]},{"word":"stehen bleiben","en":"to stop; to remain standing","ru":"останавливаться; оставаться стоять","vi":"vẫn đứng","fa":"ایستاده بماند","examples":[{"de":"Die Uhr ist gestern stehen geblieben.","en":"The clock stopped yesterday.","ru":"Часы вчера остановились.","vi":"Đồng hồ đã dừng ngày hôm qua.","fa":"ساعت دیروز متوقف شد."},{"de":"Bleib stehen, ich muss dir etwas sagen!","en":"Stop, I need to tell you something!","ru":"Остановись, мне нужно тебе кое-что сказать!","vi":"Dừng lại, tôi phải nói với bạn một điều!","fa":"بس کن، باید یه چیزی بهت بگم!"}]},{"word":"stehenbleiben","en":"to stop; to come to a standstill","ru":"останавливаться, замирать","vi":"dừng lại","fa":"توقف","examples":[{"de":"Bitte nicht stehenbleiben, der Ausgang ist dort vorne.","en":"Please don't stop, the exit is straight ahead.","ru":"Пожалуйста, не останавливайтесь, выход прямо впереди.","vi":"Làm ơn đừng dừng lại, lối ra ở ngay kia.","fa":"لطفا متوقف نشوید، خروجی همانجاست."},{"de":"Die Zeit scheint hier stehenzubleiben.","en":"Time seems to stand still here.","ru":"Кажется, время здесь остановилось.","vi":"Thời gian dường như đứng yên ở đây.","fa":"به نظر می رسد زمان در اینجا متوقف شده است."},{"de":"Der Aufzug ist zwischen zwei Stockwerken stehengeblieben.","en":"The lift got stuck between two floors.","ru":"Лифт застрял между двумя этажами.","vi":"Thang máy dừng lại giữa hai tầng.","fa":"آسانسور بین دو طبقه ایستاد."}]},{"word":"stehlen","en":"to steal","ru":"красть","vi":"ăn trộm","fa":"دزدیدن","examples":[{"de":"Jemand hat ihm das Fahrrad gestohlen.","en":"Someone stole his bicycle.","ru":"Кто-то украл у него велосипед.","vi":"Ai đó đã lấy trộm chiếc xe đạp của anh ấy.","fa":"یک نفر دوچرخه اش را دزدید."},{"de":"Man soll nicht stehlen.","en":"One should not steal.","ru":"Нельзя воровать.","vi":"Bạn không nên ăn trộm.","fa":"تو نباید دزدی کنی"}]},{"word":"steigen","en":"to climb; to rise; to increase","ru":"подниматься; расти","vi":"tăng lên","fa":"بالا آمدن","examples":[{"de":"Die Preise steigen jedes Jahr.","en":"Prices rise every year.","ru":"Цены растут каждый год.","vi":"Giá tăng hàng năm.","fa":"قیمت ها هر سال افزایش می یابد."},{"de":"Wir sind auf den Berg gestiegen.","en":"We climbed the mountain.","ru":"Мы поднялись на гору.","vi":"Chúng tôi leo lên núi.","fa":"از کوه بالا رفتیم."}]},{"word":"die Steigerung","en":"increase","ru":"рост, повышение, увеличение","vi":"sự gia tăng","fa":"افزایش","examples":[{"de":"Die Firma rechnet mit einer Steigerung der Verkäufe.","en":"The company expects an increase in sales.","ru":"Фирма рассчитывает на рост продаж.","vi":"Công ty kỳ vọng doanh số bán hàng sẽ tăng.","fa":"این شرکت انتظار دارد فروش افزایش یابد."},{"de":"Eine Steigerung der Preise war zu erwarten.","en":"An increase in prices was to be expected.","ru":"Повышение цен было ожидаемым.","vi":"Sự tăng giá đã được mong đợi.","fa":"انتظار افزایش قیمت ها بود."},{"de":"Die Steigerung seiner Leistung überraschte alle.","en":"The increase in his performance surprised everyone.","ru":"Рост его результатов удивил всех.","vi":"Sự gia tăng hiệu suất của anh ấy làm mọi người ngạc nhiên.","fa":"افزایش عملکرد او همه را شگفت زده کرد."}]},{"word":"steil","en":"steep","ru":"крутой","vi":"dốc","fa":"شیب دار","examples":[{"de":"Der Weg zum Gipfel ist sehr steil.","en":"The path to the summit is very steep.","ru":"Тропа к вершине очень крутая.","vi":"Đường lên đỉnh rất dốc.","fa":"مسیر قله بسیار شیب دار است."},{"de":"Sei vorsichtig, die Treppe ist steil.","en":"Be careful, the stairs are steep.","ru":"Будь осторожен, лестница крутая.","vi":"Hãy cẩn thận, cầu thang dốc.","fa":"مراقب باشید، پله ها شیب دار هستند."}]},{"word":"der Stein","en":"stone","ru":"камень","vi":"hòn đá","fa":"سنگ","examples":[{"de":"Die Kinder haben Steine in den See geworfen.","en":"The children threw stones into the lake.","ru":"Дети бросали камни в озеро.","vi":"Bọn trẻ ném đá xuống hồ.","fa":"بچه ها به دریاچه سنگ پرتاب کردند."},{"de":"Das alte Haus ist aus Stein gebaut.","en":"The old house is built of stone.","ru":"Старый дом построен из камня.","vi":"Ngôi nhà cổ được xây bằng đá.","fa":"خانه قدیمی از سنگ ساخته شده است."}]},{"word":"die Stelle","en":"place; spot; job/position","ru":"место; должность","vi":"nơi","fa":"مکان","examples":[{"de":"An dieser Stelle stand früher ein altes Gebäude.","en":"There used to be an old building at this spot.","ru":"На этом месте раньше стояло старое здание.","vi":"Đã từng có một tòa nhà cũ trên trang web này.","fa":"قبلا یک ساختمان قدیمی در این سایت وجود داشت."},{"de":"Sie hat endlich eine feste Stelle gefunden.","en":"She has finally found a permanent job.","ru":"Она наконец нашла постоянную должность.","vi":"Cuối cùng cô đã tìm được một công việc lâu dài.","fa":"او بالاخره یک شغل دائمی پیدا کرده است."}]},{"word":"stellen","en":"to put; to place","ru":"ставить","vi":"đặt","fa":"قرار دادن","examples":[{"de":"Stell die Tasche bitte neben die Tür.","en":"Please put the bag next to the door.","ru":"Поставь, пожалуйста, сумку рядом с дверью.","vi":"Vui lòng đặt túi cạnh cửa.","fa":"لطفا کیف را کنار در بگذارید."},{"de":"Er stellt immer viele Fragen im Unterricht.","en":"He always asks a lot of questions in class.","ru":"Он всегда задаёт много вопросов на уроке.","vi":"Anh ấy luôn hỏi rất nhiều câu hỏi trong lớp.","fa":"او همیشه در کلاس سوالات زیادی می پرسد."}]},{"word":"die Stellenanzeige","en":"job advertisement","ru":"объявление о вакансии","vi":"quảng cáo việc làm","fa":"آگهی استخدام","examples":[{"de":"Ich habe eine interessante Stellenanzeige in der Zeitung gefunden.","en":"I found an interesting job advertisement in the newspaper.","ru":"Я нашёл интересное объявление о вакансии в газете.","vi":"Tôi tìm thấy một quảng cáo việc làm thú vị trên báo.","fa":"یک آگهی کار جالب در روزنامه پیدا کردم."},{"de":"Die Stellenanzeige verlangt drei Jahre Berufserfahrung.","en":"The job advertisement asks for three years of work experience.","ru":"Объявление о вакансии требует трёх лет опыта работы.","vi":"Quảng cáo tuyển dụng yêu cầu ba năm kinh nghiệm chuyên môn.","fa":"آگهی استخدام به سه سال سابقه کار حرفه ای نیاز دارد."},{"de":"Auf die Stellenanzeige haben sich viele Leute beworben.","en":"Many people applied for the job advertisement.","ru":"На это объявление о вакансии откликнулось много людей.","vi":"Nhiều người đã nộp đơn xin việc.","fa":"افراد زیادی برای آگهی استخدام اقدام کردند."}]},{"word":"die Stellung","en":"pose, position","ru":"поза, положение","vi":"vị trí","fa":"موقعیت","examples":[{"de":"Die Stellung des Kriegers stärkt die Beine.","en":"The warrior pose strengthens the legs.","ru":"Поза воина укрепляет ноги.","vi":"Tư thế chiến binh tăng cường sức mạnh cho đôi chân.","fa":"ژست جنگجو پاها را تقویت می کند."},{"de":"Halte diese Stellung für fünf Atemzüge.","en":"Hold this pose for five breaths.","ru":"Удерживай эту позу на пять вдохов.","vi":"Giữ tư thế này trong năm nhịp thở.","fa":"این وضعیت را برای پنج نفس نگه دارید."},{"de":"Der Lehrer zeigte uns eine neue Stellung.","en":"The teacher showed us a new pose.","ru":"Преподаватель показал нам новую позу.","vi":"Giáo viên chỉ cho chúng tôi một vị trí mới.","fa":"معلم موقعیت جدیدی را به ما نشان داد."}]},{"word":"der Stempel","en":"stamp (rubber stamp)","ru":"печать; штамп","vi":"con tem","fa":"تمبر","examples":[{"de":"Der Beamte drückte einen Stempel auf das Dokument.","en":"The official stamped the document.","ru":"Чиновник поставил печать на документ.","vi":"Viên chức đóng dấu vào tài liệu.","fa":"افسر روی سند مهر زد."},{"de":"Ohne Stempel ist das Formular nicht gültig.","en":"Without a stamp the form is not valid.","ru":"Без печати бланк недействителен.","vi":"Mẫu đơn không hợp lệ nếu không có tem.","fa":"فرم بدون مهر معتبر نیست."}]},{"word":"sterben","en":"to die","ru":"умирать","vi":"chết","fa":"بمیر","examples":[{"de":"Ihr Großvater ist letztes Jahr gestorben.","en":"Her grandfather died last year.","ru":"Её дедушка умер в прошлом году.","vi":"Ông nội cô qua đời năm ngoái.","fa":"پدربزرگش سال گذشته فوت کرد."},{"de":"Viele Tierarten sterben aus.","en":"Many animal species are dying out.","ru":"Многие виды животных вымирают.","vi":"Nhiều loài động vật đang bị tuyệt chủng.","fa":"بسیاری از گونه های جانوری در حال انقراض هستند."}]},{"word":"der Stern","en":"star (sky)","ru":"звезда (небесное тело)","vi":"ngôi sao","fa":"ستاره","examples":[{"de":"Nachts kann man am Himmel viele Sterne sehen.","en":"At night you can see many stars in the sky.","ru":"Ночью на небе можно увидеть много звёзд.","vi":"Vào ban đêm bạn có thể nhìn thấy nhiều ngôi sao trên bầu trời.","fa":"در شب می توانید ستاره های زیادی را در آسمان ببینید."},{"de":"Am Himmel leuchtete ein heller Stern.","en":"A bright star shone in the sky.","ru":"На небе сияла яркая звезда.","vi":"Một ngôi sao sáng tỏa sáng trên bầu trời.","fa":"ستاره ای درخشان در آسمان می درخشید."}]},{"word":"das Sternbild","en":"constellation","ru":"созвездие","vi":"chòm sao","fa":"صورت فلکی","examples":[{"de":"Das bekannteste Sternbild ist wohl der Große Wagen.","en":"The best-known constellation is probably the Big Dipper.","ru":"Самое известное созвездие — это, пожалуй, Большая Медведица.","vi":"Chòm sao nổi tiếng nhất có lẽ là Bắc Đẩu.","fa":"معروف ترین صورت فلکی احتمالا دب اکبر است."},{"de":"Mein Sternbild ist Löwe.","en":"My star sign is Leo.","ru":"Мой знак зодиака — Лев.","vi":"Dấu hiệu ngôi sao của tôi là Leo.","fa":"My star sign is Leo."},{"de":"Kannst du dieses Sternbild am Himmel finden?","en":"Can you find this constellation in the sky?","ru":"Ты можешь найти это созвездие на небе?","vi":"Bạn có thể tìm thấy chòm sao này trên bầu trời không?","fa":"آیا می توانید این صورت فلکی را در آسمان پیدا کنید؟"}]},{"word":"der Sternenhimmel","en":"starry sky","ru":"звёздное небо","vi":"bầu trời đầy sao","fa":"the starry sky","examples":[{"de":"Der Sternenhimmel über den Bergen war atemberaubend.","en":"The starry sky over the mountains was breathtaking.","ru":"Звёздное небо над горами было захватывающим.","vi":"Bầu trời đầy sao trên những ngọn núi thật ngoạn mục.","fa":"آسمان پر ستاره بر فراز کوه ها نفس گیر بود."},{"de":"Wir legten uns ins Gras und betrachteten den Sternenhimmel.","en":"We lay down in the grass and looked at the starry sky.","ru":"Мы легли в траву и рассматривали звёздное небо.","vi":"Chúng tôi nằm xuống bãi cỏ và ngắm nhìn bầu trời đầy sao.","fa":"روی چمن ها دراز کشیدیم و به آسمان پر ستاره نگاه کردیم."},{"de":"In der Stadt ist der Sternenhimmel kaum zu sehen.","en":"In the city the starry sky is barely visible.","ru":"В городе звёздное небо почти не видно.","vi":"Ở thành phố bạn khó có thể nhìn thấy bầu trời đầy sao.","fa":"در شهر به سختی می توانید آسمان پر ستاره را ببینید."}]},{"word":"die Sternwarte","en":"observatory","ru":"обсерватория","vi":"đài quan sát","fa":"the observatory","examples":[{"de":"Von der Sternwarte aus beobachten Forscher den Nachthimmel.","en":"From the observatory researchers watch the night sky.","ru":"Из обсерватории исследователи наблюдают ночное небо.","vi":"Các nhà nghiên cứu quan sát bầu trời đêm từ đài thiên văn.","fa":"محققان آسمان شب را از رصدخانه رصد می کنند."},{"de":"Die Sternwarte besitzt ein sehr großes Teleskop.","en":"The observatory has a very large telescope.","ru":"У обсерватории есть очень большой телескоп.","vi":"Đài thiên văn có một kính thiên văn rất lớn.","fa":"این رصدخانه یک تلسکوپ بسیار بزرگ دارد."},{"de":"Am Wochenende kann man die Sternwarte besichtigen.","en":"At the weekend you can visit the observatory.","ru":"По выходным можно осмотреть обсерваторию.","vi":"Bạn có thể ghé thăm đài quan sát vào cuối tuần.","fa":"می توانید آخر هفته ها از رصدخانه دیدن کنید."}]},{"word":"die Steuer","en":"tax","ru":"налог","vi":"thuế","fa":"مالیات","examples":[{"de":"Jeder Arbeitnehmer muss Steuern zahlen.","en":"Every employee has to pay taxes.","ru":"Каждый работник должен платить налоги.","vi":"Mọi nhân viên đều phải đóng thuế.","fa":"هر کارمند باید مالیات بپردازد."},{"de":"Die Steuer auf Benzin ist in diesem Land hoch.","en":"The tax on gasoline is high in this country.","ru":"Налог на бензин в этой стране высокий.","vi":"Thuế xăng ở nước này rất cao.","fa":"مالیات بر بنزین در این کشور بالاست."}]},{"word":"der Steuerzahler","en":"taxpayer","ru":"налогоплательщик","vi":"người nộp thuế","fa":"مالیات دهنده","examples":[{"de":"Der Steuerzahler finanziert die öffentlichen Dienste.","en":"The taxpayer finances the public services.","ru":"Налогоплательщик финансирует государственные услуги.","vi":"Người nộp thuế tài trợ cho các dịch vụ công.","fa":"مالیات دهندگان خدمات عمومی را تامین مالی می کنند."},{"de":"Jeder Steuerzahler muss eine Erklärung abgeben.","en":"Every taxpayer has to submit a return.","ru":"Каждый налогоплательщик должен подать декларацию.","vi":"Mọi người nộp thuế đều phải nộp tờ khai.","fa":"هر مؤدی باید یک اظهارنامه ارائه کند."},{"de":"Das Projekt kostet den Steuerzahler viel Geld.","en":"The project costs the taxpayer a lot of money.","ru":"Проект обходится налогоплательщику в большие деньги.","vi":"Dự án tiêu tốn của người nộp thuế rất nhiều tiền.","fa":"این پروژه برای مالیات دهندگان هزینه زیادی دارد."}]},{"word":"der Steward","en":"steward (flight attendant)","ru":"стюард","vi":"tiếp viên hàng không (nam)","fa":"مهماندار","examples":[{"de":"Der Steward bringt uns während des Fluges etwas zu trinken.","en":"The steward brings us something to drink during the flight.","ru":"Стюард приносит нам что-нибудь попить во время полёта.","vi":"Tiếp viên mang cho chúng tôi thứ gì đó để uống trong suốt chuyến bay.","fa":"مهماندار در طول پرواز برای ما چیزی برای نوشیدن می آورد."},{"de":"Er arbeitet seit zwei Jahren als Steward bei einer Fluggesellschaft.","en":"He has been working as a steward for an airline for two years.","ru":"Он уже два года работает стюардом в авиакомпании.","vi":"Anh ấy đã làm tiếp viên tại một hãng hàng không được hai năm.","fa":"او دو سال است که به عنوان مهماندار در یک شرکت هواپیمایی کار می کند."}]},{"word":"die Stewardess","en":"stewardess, air hostess","ru":"стюардесса, бортпроводница","vi":"cô tiếp viên","fa":"مهماندار","examples":[{"de":"Die Stewardess zeigte uns, wo die Notausgänge sind.","en":"The stewardess showed us where the emergency exits are.","ru":"Стюардесса показала нам, где находятся аварийные выходы.","vi":"Cô tiếp viên chỉ cho chúng tôi lối thoát hiểm ở đâu.","fa":"مهماندار محل خروجی های اضطراری را به ما نشان داد."},{"de":"Eine freundliche Stewardess brachte mir ein Glas Wasser.","en":"A friendly stewardess brought me a glass of water.","ru":"Приветливая стюардесса принесла мне стакан воды.","vi":"Một cô tiếp viên thân thiện mang cho tôi một cốc nước.","fa":"مهماندار مهربانی برایم لیوان آب آورد."},{"de":"Meine Schwester arbeitet seit zwei Jahren als Stewardess.","en":"My sister has been working as a stewardess for two years.","ru":"Моя сестра уже два года работает стюардессой.","vi":"Em gái tôi đã làm tiếp viên được hai năm.","fa":"خواهرم دو سال است که به عنوان مهماندار کار می کند."}]},{"word":"der Stiefel","en":"boot","ru":"сапог; ботинок","vi":"chiếc ủng","fa":"چکمه","examples":[{"de":"Im Winter trage ich immer warme Stiefel.","en":"In winter I always wear warm boots.","ru":"Зимой я всегда ношу тёплые сапоги.","vi":"Vào mùa đông tôi luôn đi ủng ấm.","fa":"در زمستان همیشه چکمه های گرم می پوشم."},{"de":"Diese Stiefel sind wasserdicht.","en":"These boots are waterproof.","ru":"Эти сапоги водонепроницаемые.","vi":"Những đôi ủng này không thấm nước.","fa":"این چکمه ها ضد آب هستند."}]},{"word":"die Stiege","en":"staircase (Austrian usage)","ru":"лестница","vi":"cầu thang","fa":"پله ها","examples":[{"de":"Die Stiege zum Dachboden ist sehr schmal.","en":"The staircase to the attic is very narrow.","ru":"Лестница на чердак очень узкая.","vi":"Cầu thang lên gác mái rất hẹp.","fa":"پله های اتاق زیر شیروانی بسیار باریک است."},{"de":"Er ist über die Stiege nach oben gegangen.","en":"He went up the stairs.","ru":"Он поднялся наверх по лестнице.","vi":"Anh ấy đi lên cầu thang.","fa":"از پله ها بالا رفت."}]},{"word":"das Stiegenhaus","en":"stairwell (Austrian usage)","ru":"лестничная клетка","vi":"cầu thang","fa":"راه پله","examples":[{"de":"Im Stiegenhaus riecht es nach frischer Farbe.","en":"The stairwell smells of fresh paint.","ru":"В подъезде пахнет свежей краской.","vi":"Cầu thang thơm mùi sơn mới.","fa":"راه پله بوی رنگ تازه می دهد."},{"de":"Die Nachbarn treffen sich oft im Stiegenhaus.","en":"The neighbors often meet in the stairwell.","ru":"Соседи часто встречаются на лестничной клетке.","vi":"Hàng xóm thường gặp nhau ở cầu thang.","fa":"همسایه ها اغلب در راه پله ملاقات می کنند."}]},{"word":"der Stift","en":"pen; pencil","ru":"карандаш; ручка","vi":"cây bút","fa":"قلم","examples":[{"de":"Kannst du mir bitte einen Stift leihen?","en":"Can you lend me a pen, please?","ru":"Можешь одолжить мне карандаш, пожалуйста?","vi":"Bạn có thể cho tôi mượn một cây bút được không?","fa":"میشه یه خودکار بهم قرض بدی لطفا؟"},{"de":"Der Stift ist leer, ich brauche einen neuen.","en":"The pen is empty, I need a new one.","ru":"Ручка кончилась, мне нужна новая.","vi":"Cây bút đã hết, tôi cần một cái mới.","fa":"خودکار خالی است، به یک قلم جدید نیاز دارم."}]},{"word":"der Stil","en":"style","ru":"стиль","vi":"phong cách","fa":"سبک","examples":[{"de":"Sie hat einen sehr eigenen Stil beim Schreiben.","en":"She has a very individual style of writing.","ru":"У неё очень своеобразный стиль письма.","vi":"Cô ấy có phong cách viết rất độc đáo.","fa":"او سبک نوشتاری بسیار منحصر به فردی دارد."},{"de":"Das Haus ist im modernen Stil eingerichtet.","en":"The house is furnished in a modern style.","ru":"Дом обставлен в современном стиле.","vi":"Ngôi nhà được trang bị nội thất theo phong cách hiện đại.","fa":"خانه به سبک مدرن مبله شده است."}]},{"word":"stilistisch","en":"stylistic","ru":"стилистический","vi":"về mặt phong cách","fa":"از نظر سبک","examples":[{"de":"Der Text enthält einige stilistische Fehler.","en":"The text contains a few stylistic errors.","ru":"В тексте есть несколько стилистических ошибок.","vi":"Văn bản có một số lỗi về văn phong.","fa":"متن حاوی برخی اشتباهات سبکی است."},{"de":"Stilistisch ist der Roman wirklich gelungen.","en":"Stylistically the novel is really accomplished.","ru":"Стилистически роман действительно удался.","vi":"Về mặt phong cách, cuốn tiểu thuyết thực sự thành công.","fa":"از نظر سبکی، رمان واقعاً موفق است."},{"de":"Die Lehrerin gab mir stilistische Verbesserungen.","en":"The teacher gave me stylistic improvements.","ru":"Учительница внесла мне стилистические правки.","vi":"Giáo viên đã cho tôi những cải tiến về văn phong.","fa":"معلم به من بهبودهای سبکی داد."}]},{"word":"still","en":"quiet; silent; still","ru":"тихий; спокойный","vi":"im lặng","fa":"ساکت","examples":[{"de":"In der Bibliothek muss man still sein.","en":"You have to be quiet in the library.","ru":"В библиотеке нужно вести себя тихо.","vi":"Bạn phải im lặng trong thư viện.","fa":"شما باید در کتابخانه ساکت باشید."},{"de":"Der See lag still und ruhig vor uns.","en":"The lake lay still and calm before us.","ru":"Озеро лежало перед нами тихое и спокойное.","vi":"Mặt hồ nằm tĩnh lặng trước mặt chúng tôi.","fa":"دریاچه در مقابل ما آرام و آرام بود."}]},{"word":"die Stimme","en":"voice","ru":"голос","vi":"giọng nói","fa":"صدا","examples":[{"de":"Sie hat eine sehr schöne Singstimme.","en":"She has a very beautiful singing voice.","ru":"У неё очень красивый певческий голос.","vi":"Cô ấy có giọng hát rất hay.","fa":"او صدای خوانندگی بسیار زیبایی دارد."},{"de":"Ich habe seine Stimme sofort am Telefon erkannt.","en":"I recognized his voice on the phone immediately.","ru":"Я сразу узнал его голос по телефону.","vi":"Tôi nhận ra giọng nói của anh ngay trên điện thoại.","fa":"بلافاصله صدایش را در تلفن تشخیص دادم."}]},{"word":"stimmen","en":"to be correct/right; to vote","ru":"быть верным; голосовать","vi":"đồng ý","fa":"موافق","examples":[{"de":"Deine Rechnung stimmt leider nicht.","en":"Unfortunately, your calculation is not correct.","ru":"К сожалению, твой расчёт неверен.","vi":"Thật không may, tính toán của bạn không chính xác.","fa":"متأسفانه محاسبه شما نادرست است."},{"de":"Bei der Wahl stimmten viele Bürger für den neuen Kandidaten.","en":"In the election, many citizens voted for the new candidate.","ru":"На выборах многие граждане проголосовали за нового кандидата.","vi":"Trong cuộc bầu cử, nhiều người dân đã bỏ phiếu cho ứng cử viên mới.","fa":"در انتخابات بسیاری از شهروندان به نامزد جدید رای دادند."}]},{"word":"Das stimmt so nicht","en":"That's not quite right (disagreement)","ru":"Это не совсем так (несогласие)","vi":"Điều đó không hoàn toàn đúng","fa":"این کاملا درست نیست","examples":[{"de":"Das stimmt so nicht, es war ganz anders.","en":"That's not quite right, it was completely different.","ru":"Это не совсем так, всё было совсем иначе.","vi":"Điều đó không đúng, nó hoàn toàn khác.","fa":"این درست نیست، کاملا متفاوت بود."}]},{"word":"die Stimmung","en":"mood; atmosphere","ru":"настроение; атмосфера","vi":"tâm trạng","fa":"خلق و خوی","examples":[{"de":"Auf der Party herrschte eine tolle Stimmung.","en":"There was a great atmosphere at the party.","ru":"На вечеринке царило отличное настроение.","vi":"Có một bầu không khí tuyệt vời tại bữa tiệc.","fa":"فضای بسیار خوبی در مهمانی حاکم بود."},{"de":"Er ist heute schlechter Stimmung.","en":"He's in a bad mood today.","ru":"Сегодня у него плохое настроение.","vi":"Hôm nay anh ấy có tâm trạng không tốt.","fa":"امروز حالش بد است."}]},{"word":"stinken","en":"to stink","ru":"вонять","vi":"hôi thối","fa":"بوی تعفن","examples":[{"de":"Der Müll im Hof stinkt schon seit Tagen.","en":"The trash in the yard has been stinking for days.","ru":"Мусор во дворе воняет уже несколько дней.","vi":"Rác trong sân đã bốc mùi mấy ngày nay.","fa":"زباله های حیاط چند روزی است که بو می دهد."},{"de":"Es stinkt hier nach Zigarettenrauch.","en":"It stinks of cigarette smoke here.","ru":"Здесь воняет сигаретным дымом.","vi":"Ở đây có mùi khói thuốc lá.","fa":"اینجا بوی دود سیگار می دهد."}]},{"word":"stinksauer","en":"livid; absolutely furious","ru":"разъярённый, взбешённый","vi":"bực mình","fa":"عصبانی","examples":[{"de":"Mein Chef war stinksauer wegen der Verspätung.","en":"My boss was livid about the delay.","ru":"Мой начальник был в ярости из-за опоздания.","vi":"Sếp tôi rất tức giận vì sự chậm trễ.","fa":"رئیس من به خاطر تاخیر عصبانی بود."},{"de":"Sie ist stinksauer auf ihren Bruder.","en":"She's absolutely furious with her brother.","ru":"Она в бешенстве на своего брата.","vi":"Cô ấy giận anh trai mình.","fa":"او از دست برادرش عصبانی است."},{"de":"Ich bin stinksauer, weil niemand Bescheid gesagt hat.","en":"I'm fuming because nobody told me.","ru":"Я вне себя, потому что никто мне не сказал.","vi":"Tôi bực mình vì không ai nói cho tôi biết.","fa":"من عصبانی هستم چون کسی به من نگفت."}]},{"word":"der Sto","en":"(fabric/material — short form)","ru":"ткань, материал (сокращённая форма)","vi":"cái Sto","fa":"Sto","examples":[{"de":"Der Sto für das neue Kleid ist sehr weich.","en":"The fabric for the new dress is very soft.","ru":"Ткань для нового платья очень мягкая.","vi":"Vải của chiếc váy mới rất mềm.","fa":"پارچه لباس جدید بسیار نرم است."},{"de":"Wir brauchen noch mehr Sto, um den Vorhang fertigzumachen.","en":"We still need more material to finish the curtain.","ru":"Нам нужно ещё материала, чтобы дошить занавеску.","vi":"Chúng ta cần thêm Sto để hoàn thành bức màn.","fa":"برای تکمیل پرده به Sto بیشتری نیاز داریم."},{"de":"Dieser Sto lässt sich gut waschen.","en":"This fabric washes well.","ru":"Эта ткань хорошо стирается.","vi":"Loại vải này rất dễ giặt.","fa":"این پارچه به راحتی قابل شستشو است."}]},{"word":"der Stock/die Etage","en":"floor; story (of a building)","ru":"этаж","vi":"sàn/tầng","fa":"کف / کف","examples":[{"de":"Unsere Wohnung liegt im dritten Stock.","en":"Our apartment is on the third floor.","ru":"Наша квартира находится на третьем этаже.","vi":"Căn hộ của chúng tôi ở trên tầng ba.","fa":"آپارتمان ما در طبقه سوم است."},{"de":"Der Aufzug fährt bis in die oberste Etage.","en":"The elevator goes up to the top floor.","ru":"Лифт едет до самого верхнего этажа.","vi":"Thang máy đi lên tầng trên cùng.","fa":"آسانسور به طبقه بالا می رود."}]},{"word":"der Stoff","en":"fabric; material; substance","ru":"ткань; материал; вещество","vi":"vật liệu","fa":"مواد","examples":[{"de":"Das Kleid ist aus einem weichen Stoff genäht.","en":"The dress is sewn from a soft fabric.","ru":"Платье сшито из мягкой ткани.","vi":"Chiếc váy được may từ chất liệu vải mềm mại.","fa":"لباس از پارچه نرم دوخته شده است."},{"de":"Dieser Stoff ist für den Menschen giftig.","en":"This substance is toxic to humans.","ru":"Это вещество токсично для человека.","vi":"Chất này độc hại đối với con người.","fa":"این ماده برای انسان سمی است."}]},{"word":"stolz","en":"proud","ru":"гордый","vi":"tự hào","fa":"افتخار","examples":[{"de":"Die Eltern sind sehr stolz auf ihre Tochter.","en":"The parents are very proud of their daughter.","ru":"Родители очень гордятся своей дочерью.","vi":"Cha mẹ rất tự hào về con gái mình.","fa":"والدین به دختر خود بسیار افتخار می کنند."},{"de":"Er ist stolz auf seine Arbeit.","en":"He is proud of his work.","ru":"Он гордится своей работой.","vi":"Anh ấy tự hào về công việc của mình.","fa":"او به کار خود افتخار می کند."}]},{"word":"der Stolz","en":"pride","ru":"гордость","vi":"niềm tự hào","fa":"غرور","examples":[{"de":"Mit Stolz zeigte sie ihr Zeugnis.","en":"She proudly showed her report card.","ru":"С гордостью она показала свой табель.","vi":"Cô tự hào đưa ra lời khai của mình.","fa":"او با افتخار شهادت خود را نشان داد."},{"de":"Sein Stolz erlaubte ihm nicht, um Hilfe zu bitten.","en":"His pride wouldn't let him ask for help.","ru":"Его гордость не позволяла ему просить о помощи.","vi":"Niềm tự hào của anh không cho phép anh yêu cầu giúp đỡ.","fa":"غرورش اجازه نمی داد کمک بخواهد."}]},{"word":"stoppen","en":"to stop","ru":"останавливать(ся); стопорить","vi":"dừng lại","fa":"توقف","examples":[{"de":"Der Fahrer musste plötzlich stoppen.","en":"The driver had to stop suddenly.","ru":"Водителю пришлось резко остановиться.","vi":"Tài xế phải dừng lại đột ngột.","fa":"راننده مجبور شد ناگهان توقف کند."},{"de":"Die Polizei stoppte das Auto an der Grenze.","en":"The police stopped the car at the border.","ru":"Полиция остановила машину на границе.","vi":"Cảnh sát dừng xe ở biên giới.","fa":"پلیس ماشین را در مرز متوقف کرد."}]},{"word":"stören","en":"to disturb; to bother","ru":"мешать; беспокоить","vi":"làm phiền","fa":"مزاحم","examples":[{"de":"Entschuldigung, störe ich dich gerade?","en":"Excuse me, am I disturbing you right now?","ru":"Извини, я тебе сейчас не мешаю?","vi":"Xin lỗi, tôi có làm phiền bạn không?","fa":"ببخشید مزاحم شما هستم؟"},{"de":"Der Lärm von der Baustelle stört die Nachbarn.","en":"The noise from the construction site disturbs the neighbors.","ru":"Шум со стройки мешает соседям.","vi":"Tiếng ồn từ công trường xây dựng làm phiền hàng xóm.","fa":"سر و صدا از محل ساخت و ساز همسایه ها را آزار می دهد."}]},{"word":"die Störung","en":"disturbance, disruption, fault","ru":"помеха, сбой, неисправность","vi":"sự rối loạn","fa":"اختلال","examples":[{"de":"Wegen einer technischen Störung fiel der Zug aus.","en":"The train was cancelled because of a technical fault.","ru":"Поезд отменили из-за технической неисправности.","vi":"Chuyến tàu bị hủy do trục trặc kỹ thuật.","fa":"قطار به دلیل نقص فنی لغو شد."},{"de":"Entschuldigen Sie die Störung, ich habe nur eine kurze Frage.","en":"Sorry to disturb you, I just have a quick question.","ru":"Простите за беспокойство, у меня всего один короткий вопрос.","vi":"Xin lỗi đã làm phiền bạn, tôi chỉ có một câu hỏi ngắn.","fa":"ببخشید مزاحمتون شدم فقط یه سوال فوری دارم"},{"de":"Es gab eine Störung im Internet, deshalb ging nichts.","en":"There was an internet outage, so nothing worked.","ru":"Был сбой в интернете, так что ничего не работало.","vi":"Internet bị gián đoạn nên không có tác dụng gì.","fa":"یک اختلال در اینترنت وجود دارد، بنابراین هیچ چیز کار نمی کند."}]},{"word":"die Story","en":"a story (a short, temporary post on a social network)","ru":"история (короткая временная публикация в соцсети)","vi":"câu chuyện","fa":"داستان","examples":[{"de":"Man kann mit anderen eine Story teilen.","en":"You can share a story with others.","ru":"Историей можно поделиться с другими.","vi":"Bạn có thể chia sẻ một câu chuyện với người khác.","fa":"می توانید داستانی را با دیگران به اشتراک بگذارید."},{"de":"In meiner Story zeige ich oft Fotos vom Wochenende.","en":"In my story I often show photos from the weekend.","ru":"В своей истории я часто показываю фото с выходных.","vi":"Tôi thường khoe những bức ảnh cuối tuần trong câu chuyện của mình.","fa":"من اغلب عکس های آخر هفته را در استوری خود نشان می دهم."},{"de":"Eine Story verschwindet nach vierundzwanzig Stunden wieder.","en":"A story disappears again after twenty-four hours.","ru":"История исчезает через двадцать четыре часа.","vi":"Một câu chuyện biến mất sau hai mươi bốn giờ.","fa":"داستانی بعد از بیست و چهار ساعت ناپدید می شود."}]},{"word":"die Stoßstange","en":"bumper (of a car)","ru":"бампер (автомобиля)","vi":"cái cản trước","fa":"سپر","examples":[{"de":"Bei dem Unfall wurde nur die Stoßstange beschädigt.","en":"In the accident only the bumper was damaged.","ru":"В аварии пострадал только бампер.","vi":"Vụ tai nạn chỉ gây hư hỏng phần cản trước.","fa":"در این تصادف فقط سپر آسیب دید."},{"de":"Die vordere Stoßstange muss repariert werden.","en":"The front bumper needs to be repaired.","ru":"Передний бампер нужно отремонтировать.","vi":"Cản trước cần được sửa chữa.","fa":"سپر جلو نیاز به تعمیر دارد."},{"de":"Er fuhr rückwärts gegen die Stoßstange des anderen Autos.","en":"He reversed into the other car's bumper.","ru":"Он въехал задом в бампер другой машины.","vi":"Anh ta lùi vào cản của chiếc xe kia.","fa":"به سپر ماشین دیگر برگشت."}]},{"word":"strafbar","en":"punishable; a criminal offence","ru":"наказуемый, уголовно наказуемый","vi":"có thể trừng phạt","fa":"قابل مجازات","examples":[{"de":"Diebstahl ist strafbar.","en":"Theft is a criminal offence.","ru":"Кража наказуема.","vi":"Trộm cắp có thể bị trừng phạt.","fa":"سرقت مجازات دارد."},{"de":"Wer beim Fahren das Handy benutzt, macht sich strafbar.","en":"Anyone using a phone while driving commits an offence.","ru":"Кто пользуется телефоном за рулём, совершает правонарушение.","vi":"Bất cứ ai sử dụng điện thoại di động khi lái xe đều phạm tội hình sự.","fa":"هر کس در حین رانندگی از تلفن همراه استفاده کند مرتکب جرم کیفری شده است."},{"de":"Solche Aussagen können strafbar sein.","en":"Such statements can be punishable.","ru":"Такие высказывания могут быть наказуемы.","vi":"Những tuyên bố như vậy có thể bị trừng phạt.","fa":"چنین اظهاراتی می تواند مجازات داشته باشد."}]},{"word":"die Strafe","en":"punishment; fine; penalty","ru":"наказание; штраф","vi":"sự trừng phạt","fa":"مجازات","examples":[{"de":"Für Falschparken muss man eine Strafe zahlen.","en":"You have to pay a fine for parking illegally.","ru":"За неправильную парковку нужно платить штраф.","vi":"Bạn phải trả tiền phạt cho việc đỗ xe trái phép.","fa":"برای پارک غیرقانونی باید جریمه بپردازید."},{"de":"Die Strafe für dieses Verbrechen ist sehr hoch.","en":"The punishment for this crime is very severe.","ru":"Наказание за это преступление очень суровое.","vi":"Mức án cho tội này rất cao.","fa":"مجازات این جنایت بسیار زیاد است."}]},{"word":"der Strafzettel","en":"parking ticket, penalty notice","ru":"штрафная квитанция, штраф за парковку","vi":"vé giao thông","fa":"بلیط ترافیک","examples":[{"de":"An meinem Auto klebte heute Morgen ein Strafzettel.","en":"There was a parking ticket on my car this morning.","ru":"Сегодня утром на моей машине был штраф за парковку.","vi":"Sáng nay có một tấm vé đỗ xe dính vào xe tôi.","fa":"امروز صبح یه بلیط پارکینگ به ماشینم چسبیده بود."},{"de":"Ich habe schon wieder einen Strafzettel bekommen.","en":"I've got a parking ticket again.","ru":"Я снова получил штрафную квитанцию.","vi":"Tôi lại nhận được một vé phạt quá tốc độ.","fa":"من یک بلیط سرعت دیگر گرفتم."},{"de":"Der Strafzettel kostet mich dreißig Euro.","en":"The penalty notice costs me thirty euros.","ru":"Штрафная квитанция обойдётся мне в тридцать евро.","vi":"Vé phạt chạy quá tốc độ khiến tôi tốn ba mươi euro.","fa":"بلیط سرعت برای من سی یورو قیمت دارد."}]},{"word":"der Strand","en":"beach","ru":"пляж","vi":"bãi biển","fa":"ساحل","examples":[{"de":"Im Sommer verbringen wir viel Zeit am Strand.","en":"In summer we spend a lot of time at the beach.","ru":"Летом мы проводим много времени на пляже.","vi":"Vào mùa hè, chúng tôi dành nhiều thời gian trên bãi biển.","fa":"در تابستان زمان زیادی را در ساحل می گذرانیم."},{"de":"Der Strand war heute sehr voll.","en":"The beach was very crowded today.","ru":"Пляж сегодня был очень многолюдным.","vi":"Bãi biển hôm nay rất đông người.","fa":"امروز ساحل خیلی شلوغ بود."}]},{"word":"der Strandurlaub","en":"beach holiday","ru":"пляжный отдых","vi":"kỳ nghỉ ở bãi biển","fa":"تعطیلات ساحلی","examples":[{"de":"Dieses Jahr machen wir einen Strandurlaub in Italien.","en":"This year we're having a beach holiday in Italy.","ru":"В этом году у нас пляжный отдых в Италии.","vi":"Năm nay chúng tôi sẽ đi nghỉ ở bãi biển ở Ý.","fa":"امسال به تعطیلات ساحلی در ایتالیا می رویم."},{"de":"Ein Strandurlaub ist genau das Richtige zum Entspannen.","en":"A beach holiday is just the thing for relaxing.","ru":"Пляжный отдых — как раз то, что нужно для отдыха.","vi":"Một kỳ nghỉ ở bãi biển chỉ là điều để thư giãn.","fa":"تعطیلات ساحلی تنها چیزی است که می توانید استراحت کنید."},{"de":"Beim Strandurlaub liege ich am liebsten in der Sonne.","en":"On a beach holiday I most like to lie in the sun.","ru":"На пляжном отдыхе я больше всего люблю лежать на солнце.","vi":"Khi tôi đi nghỉ ở bãi biển, tôi thích nằm phơi nắng hơn.","fa":"وقتی به تعطیلات ساحلی می روم، ترجیح می دهم زیر آفتاب دراز بکشم."}]},{"word":"die Straße","en":"street; road","ru":"улица; дорога","vi":"đường phố","fa":"خیابان","examples":[{"de":"Wir wohnen in einer ruhigen Straße.","en":"We live on a quiet street.","ru":"Мы живём на тихой улице.","vi":"Chúng tôi sống trên một con phố yên tĩnh.","fa":"ما در یک خیابان ساکت زندگی می کنیم."},{"de":"Auf der Straße war heute viel Verkehr.","en":"There was a lot of traffic on the road today.","ru":"На дороге сегодня было много машин.","vi":"Hôm nay trên đường phố có rất nhiều xe cộ qua lại.","fa":"امروز ترافیک زیادی در خیابان وجود داشت."}]},{"word":"die Straßenbahn","en":"tram; streetcar","ru":"трамвай","vi":"xe điện","fa":"تراموا","examples":[{"de":"Ich fahre jeden Tag mit der Straßenbahn zur Arbeit.","en":"I take the tram to work every day.","ru":"Я каждый день езжу на работу на трамвае.","vi":"Tôi đi xe điện đi làm hàng ngày.","fa":"من هر روز با تراموا سر کار می روم."},{"de":"Die Straßenbahn hält direkt vor unserem Haus.","en":"The tram stops right in front of our house.","ru":"Трамвай останавливается прямо перед нашим домом.","vi":"Xe điện dừng ngay trước nhà chúng tôi.","fa":"تراموا درست جلوی خانه ما می ایستد."}]},{"word":"streamen","en":"to stream (media)","ru":"транслировать в потоке, стримить (медиа)","vi":"dòng suối","fa":"جریان","examples":[{"de":"Wir streamen heute Abend einen neuen Film.","en":"We're streaming a new film tonight.","ru":"Сегодня вечером мы стримим новый фильм.","vi":"Tối nay chúng tôi sẽ chiếu một bộ phim mới.","fa":"ما امشب یک فیلم جدید را پخش می کنیم."},{"de":"Sie streamt jeden Tag Musik auf dem Handy.","en":"She streams music on her phone every day.","ru":"Она каждый день слушает музыку по стримингу на телефоне.","vi":"Cô ấy phát nhạc trên điện thoại của mình mỗi ngày.","fa":"او هر روز از تلفن خود موسیقی پخش می کند."},{"de":"Das Konzert wurde live ins Internet gestreamt.","en":"The concert was streamed live on the internet.","ru":"Концерт транслировали вживую в интернете.","vi":"Buổi hòa nhạc được phát trực tiếp trên Internet.","fa":"این کنسرت به صورت زنده از طریق اینترنت پخش شد."}]},{"word":"die Strecke","en":"distance; route; stretch","ru":"маршрут; расстояние; участок пути","vi":"tuyến đường","fa":"مسیر","examples":[{"de":"Die Strecke von Wien nach Salzburg dauert etwa drei Stunden.","en":"The route from Vienna to Salzburg takes about three hours.","ru":"Путь из Вены в Зальцбург занимает около трёх часов.","vi":"Tuyến đường từ Vienna đến Salzburg mất khoảng ba giờ.","fa":"مسیر وین تا سالزبورگ حدود سه ساعت طول می کشد."},{"de":"Wir sind eine lange Strecke zu Fuß gelaufen.","en":"We walked a long distance on foot.","ru":"Мы прошли пешком длинное расстояние.","vi":"Chúng tôi đi bộ một quãng đường dài.","fa":"مسافت زیادی را پیاده رفتیم."}]},{"word":"streichen","en":"to paint; to cross out; to cancel","ru":"красить; вычёркивать; отменять","vi":"xóa","fa":"حذف کنید","examples":[{"de":"Wir streichen die Wände im Wohnzimmer weiß.","en":"We're painting the living-room walls white.","ru":"Мы красим стены в гостиной в белый цвет.","vi":"Chúng tôi đang sơn tường phòng khách màu trắng.","fa":"ما در حال رنگ آمیزی دیوارهای اتاق نشیمن به رنگ سفید هستیم."},{"de":"Bitte streichen Sie das falsche Wort.","en":"Please cross out the wrong word.","ru":"Вычеркните, пожалуйста, неправильное слово.","vi":"Hãy xóa từ sai.","fa":"لطفا کلمه اشتباه را حذف کنید."},{"de":"Der Flug wurde wegen des Sturms gestrichen.","en":"The flight was cancelled because of the storm.","ru":"Рейс отменили из-за бури.","vi":"Chuyến bay bị hủy do bão.","fa":"این پرواز به دلیل طوفان لغو شد."}]},{"word":"das Streichholz","en":"match (for lighting)","ru":"спичка","vi":"trận đấu","fa":"کبریت","examples":[{"de":"Er zündete die Kerze mit einem Streichholz an.","en":"He lit the candle with a match.","ru":"Он зажёг свечу спичкой.","vi":"Anh ta thắp nến bằng một que diêm.","fa":"شمع را با کبریت روشن کرد."},{"de":"Hast du zufällig ein Streichholz dabei?","en":"Do you happen to have a match with you?","ru":"У тебя случайно нет с собой спички?","vi":"Bạn có tình cờ có một trận đấu với bạn?","fa":"آیا اتفاقاً با شما مسابقه ای دارید؟"}]},{"word":"der Streik","en":"strike","ru":"забастовка","vi":"cuộc đình công","fa":"اعتصاب","examples":[{"de":"Wegen des Streiks fahren heute keine Züge.","en":"Because of the strike no trains are running today.","ru":"Из-за забастовки сегодня не ходят поезда.","vi":"Hôm nay không có chuyến tàu nào chạy vì cuộc đình công.","fa":"امروز به دلیل اعتصاب هیچ قطاری حرکت نمی کند."},{"de":"Die Beschäftigten traten in den Streik.","en":"The employees went on strike.","ru":"Сотрудники объявили забастовку.","vi":"Các công nhân đã đình công.","fa":"کارگران دست به اعتصاب زدند."},{"de":"Der Streik dauerte mehrere Tage.","en":"The strike lasted several days.","ru":"Забастовка длилась несколько дней.","vi":"Cuộc đình công kéo dài vài ngày.","fa":"این اعتصاب چند روز به طول انجامید."}]},{"word":"streiken","en":"to (go on) strike","ru":"бастовать","vi":"đình công","fa":"اعتصاب","examples":[{"de":"Die Fluglotsen streiken morgen den ganzen Tag.","en":"The air traffic controllers are on strike all day tomorrow.","ru":"Авиадиспетчеры завтра бастуют весь день.","vi":"Ngày mai các nhân viên kiểm soát không lưu sẽ đình công cả ngày.","fa":"اعتصاب ناظران هوايي فردا تمام روز است."},{"de":"Die Arbeiter streiken für höhere Löhne.","en":"The workers are striking for higher wages.","ru":"Рабочие бастуют за повышение зарплаты.","vi":"Công nhân đình công đòi tăng lương.","fa":"کارگران برای افزایش دستمزد اعتصاب می کنند."}]},{"word":"der Streit","en":"argument; quarrel","ru":"спор, ссора","vi":"lập luận","fa":"استدلال","examples":[{"de":"Nach dem Streit haben sich die Geschwister wieder versöhnt.","en":"After the argument the siblings made up again.","ru":"После ссоры братья и сёстры снова помирились.","vi":"Sau khi tranh cãi, hai anh em lại làm lành.","fa":"بعد از مشاجره، خواهر و برادر دوباره آرایش کردند."},{"de":"Es gab einen heftigen Streit über das Erbe der Großeltern.","en":"There was a fierce quarrel about the grandparents' inheritance.","ru":"Был ожесточённый спор из-за наследства бабушки и дедушки.","vi":"Có một cuộc tranh cãi nảy lửa về quyền thừa kế của ông bà.","fa":"بحث شدیدی در مورد ارث پدربزرگ و مادربزرگ وجود داشت."},{"de":"Kleine Streitigkeiten gehören in jeder Familie zum Alltag.","en":"Small quarrels are part of everyday life in every family.","ru":"Мелкие ссоры — часть повседневной жизни в каждой семье.","vi":"Những tranh chấp nhỏ là một phần trong cuộc sống hàng ngày của mỗi gia đình.","fa":"اختلافات کوچک بخشی از زندگی روزمره در هر خانواده است."}]},{"word":"streng","en":"strict","ru":"строгий","vi":"nghiêm khắc","fa":"سختگیر","examples":[{"de":"Unser Lehrer ist sehr streng.","en":"Our teacher is very strict.","ru":"Наш учитель очень строгий.","vi":"Giáo viên của chúng tôi rất nghiêm khắc.","fa":"معلم ما خیلی سخت گیر است."},{"de":"In dieser Firma gelten strenge Regeln.","en":"Strict rules apply in this company.","ru":"В этой компании действуют строгие правила.","vi":"Các quy tắc nghiêm ngặt được áp dụng trong công ty này.","fa":"قوانین سختگیرانه ای در این شرکت اعمال می شود."}]},{"word":"der Stress","en":"stress","ru":"стресс","vi":"sự căng thẳng","fa":"استرس","examples":[{"de":"Sie hat wegen der Prüfung viel Stress.","en":"She has a lot of stress because of the exam.","ru":"У неё сильный стресс из-за экзамена.","vi":"Cô ấy đang bị căng thẳng rất nhiều vì kỳ thi.","fa":"او به دلیل امتحان استرس زیادی دارد."},{"de":"Zu viel Stress ist schlecht für die Gesundheit.","en":"Too much stress is bad for your health.","ru":"Слишком сильный стресс вреден для здоровья.","vi":"Căng thẳng quá mức sẽ có hại cho sức khỏe của bạn.","fa":"استرس زیاد برای سلامتی مضر است."}]},{"word":"streuen","en":"to sprinkle; to scatter; to grit","ru":"посыпать, рассыпать; подсыпать (напр. соль на дороги)","vi":"rải rác","fa":"پراکنده کردن","examples":[{"de":"Streu etwas Zucker über den Kuchen.","en":"Sprinkle some sugar over the cake.","ru":"Посыпь немного сахара на пирог.","vi":"Rắc chút đường lên bánh.","fa":"مقداری شکر روی کیک بپاشید."},{"de":"Im Winter streut die Stadt Salz auf die Straßen.","en":"In winter the city grits salt on the roads.","ru":"Зимой город посыпает дороги солью.","vi":"Vào mùa đông, thành phố trải muối trên đường phố.","fa":"در زمستان شهر در خیابان ها نمک می پاشد."},{"de":"Sie streute die Samen gleichmäßig ins Beet.","en":"She scattered the seeds evenly in the bed.","ru":"Она равномерно рассыпала семена по грядке.","vi":"Cô rải đều hạt khắp luống.","fa":"او دانه ها را به طور مساوی در سراسر تخت پخش کرد."}]},{"word":"der Strom","en":"electricity; power; current","ru":"электричество; ток","vi":"dòng điện; dòng chảy","fa":"جریان","examples":[{"de":"Bei dem Sturm ist der Strom ausgefallen.","en":"The power went out during the storm.","ru":"Во время шторма отключилось электричество.","vi":"Mất điện trong cơn bão.","fa":"هنگام طوفان برق قطع شد."},{"de":"Wir versuchen, weniger Strom zu verbrauchen.","en":"We're trying to use less electricity.","ru":"Мы стараемся потреблять меньше электроэнергии.","vi":"Chúng tôi đang cố gắng sử dụng ít điện hơn.","fa":"سعی می کنیم کمتر از برق استفاده کنیم."}]},{"word":"der Stromkreis","en":"electric circuit","ru":"электрическая цепь","vi":"mạch","fa":"مدار","examples":[{"de":"Im geschlossenen Stromkreis fließt der Strom.","en":"In a closed circuit the current flows.","ru":"В замкнутой цепи течёт ток.","vi":"Dòng điện chạy trong một mạch kín.","fa":"جریان در یک مدار بسته جریان دارد."},{"de":"Wenn der Stromkreis unterbrochen ist, geht die Lampe aus.","en":"When the circuit is broken, the lamp goes out.","ru":"Когда цепь разомкнута, лампа гаснет.","vi":"Nếu mạch bị đứt thì đèn tắt.","fa":"اگر مدار خراب باشد، لامپ خاموش می شود."},{"de":"Wir bauen einen einfachen Stromkreis mit einer Batterie.","en":"We build a simple circuit with a battery.","ru":"Мы собираем простую цепь с батареей.","vi":"Chúng ta sẽ xây dựng một mạch điện đơn giản với một cục pin.","fa":"یک مدار ساده با باتری می سازیم."}]},{"word":"der Strumpf","en":"stocking","ru":"чулок","vi":"việc thả giống","fa":"جوراب ساق بلند","examples":[{"de":"Sie zieht warme Strümpfe an, bevor sie hinausgeht.","en":"She puts on warm stockings before going outside.","ru":"Она надевает тёплые чулки, прежде чем выйти на улицу.","vi":"Cô ấy đi tất ấm trước khi ra ngoài.","fa":"قبل از بیرون رفتن جوراب گرم می پوشد."},{"de":"Ein Strumpf hat ein Loch bekommen.","en":"One stocking got a hole in it.","ru":"На одном чулке появилась дыра.","vi":"Một chiếc tất bị thủng một lỗ.","fa":"یک جوراب ساق بلند سوراخ شد."}]},{"word":"die Strumpfhose","en":"tights, pantyhose","ru":"колготки","vi":"quần tất","fa":"جوراب شلواری","examples":[{"de":"Sie trägt eine schwarze Strumpfhose zum Kleid.","en":"She is wearing black tights with the dress.","ru":"Она надела к платью чёрные колготки.","vi":"Cô mặc quần bó màu đen với chiếc váy.","fa":"او جوراب شلواری مشکی با لباس می پوشد."},{"de":"Meine Strumpfhose hat eine Laufmasche bekommen.","en":"My tights have got a ladder in them.","ru":"На моих колготках спустилась петля.","vi":"Quần tất của tôi có một đường khâu chạy dài.","fa":"جوراب شلواری من دوخت دارد."},{"de":"Im Winter ist eine warme Strumpfhose sehr praktisch.","en":"In winter a warm pair of tights is very practical.","ru":"Зимой тёплые колготки очень практичны.","vi":"Quần tất ấm áp rất thiết thực trong mùa đông.","fa":"جوراب شلواری گرم در زمستان بسیار کاربردی است."}]},{"word":"das Stück/-stück","en":"piece","ru":"кусок; штука","vi":"mảnh / mảnh","fa":"قطعه / قطعه","examples":[{"de":"Möchtest du noch ein Stück Kuchen?","en":"Would you like another piece of cake?","ru":"Хочешь ещё кусочек торта?","vi":"Bạn có muốn một miếng bánh khác không?","fa":"آیا یک تکه کیک دیگر می خواهید؟"},{"de":"Er hat sich ein Geldstück aus der Tasche geholt.","en":"He took a coin out of his pocket.","ru":"Он достал монету из кармана.","vi":"Anh ta lấy một đồng xu ra khỏi túi.","fa":"یک سکه از جیبش در آورد."}]},{"word":"die Studie","en":"study (research)","ru":"исследование (научное)","vi":"nghiên cứu","fa":"مطالعه","examples":[{"de":"Eine neue Studie zeigt die Vorteile von regelmäßigem Sport.","en":"A new study shows the benefits of regular exercise.","ru":"Новое исследование показывает пользу регулярных занятий спортом.","vi":"Một nghiên cứu mới cho thấy lợi ích của việc tập thể dục thường xuyên.","fa":"یک مطالعه جدید فواید ورزش منظم را نشان می دهد."},{"de":"Die Studie wurde von Wissenschaftlern der Universität durchgeführt.","en":"The study was conducted by scientists at the university.","ru":"Исследование было проведено учёными университета.","vi":"Nghiên cứu được thực hiện bởi các nhà khoa học từ trường đại học.","fa":"این مطالعه توسط دانشمندان دانشگاه انجام شد."}]},{"word":"der Studiengang","en":"degree programme; course of study","ru":"направление обучения; специальность","vi":"quá trình học tập","fa":"دوره تحصیلی","examples":[{"de":"Dieser Studiengang dauert sechs Semester.","en":"This degree programme lasts six semesters.","ru":"Это направление обучения длится шесть семестров.","vi":"Khóa học này kéo dài sáu học kỳ.","fa":"این دوره شش ترم به طول می انجامد."},{"de":"Sie hat den Studiengang gewechselt.","en":"She changed her course of study.","ru":"Она сменила направление обучения.","vi":"Cô ấy đã thay đổi khóa học của mình.","fa":"او رشته تحصیلی خود را تغییر داد."}]},{"word":"studieren","en":"to study (at university)","ru":"учиться (в университете)","vi":"học tập","fa":"مطالعه کنید","examples":[{"de":"Meine Schwester studiert Medizin in Berlin.","en":"My sister is studying medicine in Berlin.","ru":"Моя сестра изучает медицину в Берлине.","vi":"Em gái tôi đang học y khoa ở Berlin.","fa":"خواهرم در برلین پزشکی می خواند."},{"de":"Nach dem Abitur möchte er Jura studieren.","en":"After finishing school, he wants to study law.","ru":"После окончания школы он хочет изучать право.","vi":"Sau khi tốt nghiệp trung học, anh muốn học luật.","fa":"او پس از پایان دبیرستان، دوست دارد در رشته حقوق تحصیل کند."}]},{"word":"die Studierende","en":"student (gender-neutral, declined adjective)","ru":"студент, студентка (нейтр., субстантивированное причастие)","vi":"các sinh viên","fa":"دانش آموزان","examples":[{"de":"Viele Studierende wohnen in einem Wohnheim.","en":"Many students live in a hall of residence.","ru":"Многие студенты живут в общежитии.","vi":"Nhiều sinh viên sống trong ký túc xá.","fa":"بسیاری از دانشجویان در یک خوابگاه زندگی می کنند."},{"de":"Die Studierenden bereiten sich auf die Prüfung vor.","en":"The students are preparing for the exam.","ru":"Студенты готовятся к экзамену.","vi":"Các em học sinh chuẩn bị cho kỳ thi.","fa":"دانش آموزان برای امتحان آماده می شوند."},{"de":"Eine Studierende stellte eine interessante Frage.","en":"A student asked an interesting question.","ru":"Один студент задал интересный вопрос.","vi":"Một sinh viên đã hỏi một câu hỏi thú vị.","fa":"دانشجویی سوال جالبی پرسید."}]},{"word":"das Studio","en":"studio","ru":"студия","vi":"studio","fa":"استودیو","examples":[{"de":"Die Band nimmt ihr neues Album im Studio auf.","en":"The band is recording their new album in the studio.","ru":"Группа записывает свой новый альбом в студии.","vi":"Ban nhạc đang thu âm album mới trong phòng thu.","fa":"گروه در حال ضبط آلبوم جدید خود در استودیو است."},{"de":"Sie wohnt in einem kleinen Studio in der Innenstadt.","en":"She lives in a small studio apartment in the city center.","ru":"Она живёт в маленькой студии в центре города.","vi":"Cô sống trong một studio nhỏ ở trung tâm thành phố.","fa":"او در یک استودیوی کوچک در مرکز شهر زندگی می کند."}]},{"word":"das Studium","en":"studies; degree course","ru":"учёба (в вузе)","vi":"nghiên cứu","fa":"مطالعه","examples":[{"de":"Nach dem Studium möchte er im Ausland arbeiten.","en":"After his studies he wants to work abroad.","ru":"После учёбы он хочет работать за границей.","vi":"Sau khi học xong anh ấy muốn làm việc ở nước ngoài.","fa":"پس از تحصیل او دوست دارد در خارج از کشور کار کند."},{"de":"Das Studium der Medizin ist sehr anspruchsvoll.","en":"Studying medicine is very demanding.","ru":"Учёба на медицинском очень требовательная.","vi":"Nghiên cứu y học là rất khắt khe.","fa":"تحصیل در رشته پزشکی بسیار سخت است."}]},{"word":"die Stufe","en":"step (stair); level","ru":"ступень(ка); уровень","vi":"bậc (thang); cấp độ","fa":"پله؛ مرحله","examples":[{"de":"Vorsicht, die Stufe ist hoch!","en":"Careful, the step is high!","ru":"Осторожно, ступенька высокая!","vi":"Hãy cẩn thận, mức độ cao!","fa":"مراقب باشید، سطح بالاست!"},{"de":"Der Kurs ist in mehrere Stufen unterteilt.","en":"The course is divided into several levels.","ru":"Курс разделён на несколько уровней.","vi":"Khóa học được chia thành nhiều cấp độ.","fa":"این دوره به چند سطح تقسیم می شود."}]},{"word":"der Stuhl","en":"chair","ru":"стул","vi":"cái ghế","fa":"صندلی","examples":[{"de":"Bitte setz dich auf diesen Stuhl.","en":"Please sit down on this chair.","ru":"Пожалуйста, сядь на этот стул.","vi":"Xin hãy ngồi vào chiếc ghế này.","fa":"لطفا روی این صندلی بنشینید."},{"de":"Der Stuhl ist kaputt, ein Bein wackelt.","en":"The chair is broken, one leg is wobbly.","ru":"Стул сломан, одна ножка шатается.","vi":"Ghế gãy, một chân lung lay.","fa":"صندلی شکسته است، یک پا تکان می خورد."}]},{"word":"stumm","en":"mute; silent","ru":"немой; безмолвный","vi":"im lặng","fa":"ساکت","examples":[{"de":"Der Junge saß stumm in der Ecke.","en":"The boy sat silently in the corner.","ru":"Мальчик сидел молча в углу.","vi":"Cậu bé ngồi im lặng trong góc.","fa":"پسر ساکت در گوشه ای نشست."},{"de":"Nach dem Unfall war sie für einige Tage stumm vor Schock.","en":"After the accident she was mute with shock for a few days.","ru":"После аварии она несколько дней была нема от шока.","vi":"Sau vụ tai nạn, cô im lặng vì sốc vài ngày.","fa":"بعد از تصادف چند روزی در شوک سکوت کرد."}]},{"word":"die Stunde","en":"hour; lesson","ru":"час; урок","vi":"giờ","fa":"ساعت","examples":[{"de":"Der Film dauert etwa zwei Stunden.","en":"The movie lasts about two hours.","ru":"Фильм длится около двух часов.","vi":"Bộ phim kéo dài khoảng hai giờ.","fa":"فیلم حدود دو ساعت طول می کشد."},{"de":"Wir haben jeden Montag eine Stunde Mathematik.","en":"We have a math lesson every Monday.","ru":"У нас каждый понедельник урок математики.","vi":"Chúng tôi có một giờ học toán vào thứ Hai hàng tuần.","fa":"هر دوشنبه یک ساعت ریاضی داریم."}]},{"word":"der Sturm","en":"storm","ru":"шторм; буря","vi":"cơn bão","fa":"طوفان","examples":[{"de":"Ein starker Sturm hat letzte Nacht viele Bäume umgeworfen.","en":"A strong storm knocked down many trees last night.","ru":"Сильная буря вчера ночью повалила много деревьев.","vi":"Đêm qua một cơn bão mạnh đã quật đổ nhiều cây cối.","fa":"طوفان شدید شب گذشته درختان زیادی را فرو ریخت."},{"de":"Wegen des Sturms wurden alle Flüge gestrichen.","en":"Because of the storm, all flights were cancelled.","ru":"Из-за шторма все рейсы были отменены.","vi":"Vì cơn bão nên tất cả các chuyến bay đều bị hủy.","fa":"به دلیل طوفان همه پروازها لغو شد."}]},{"word":"stürzen","en":"to fall (heavily); to crash","ru":"падать, рухнуть","vi":"ngã","fa":"سقوط","examples":[{"de":"Der alte Mann ist auf der Treppe gestürzt.","en":"The old man fell on the stairs.","ru":"Пожилой мужчина упал на лестнице.","vi":"Ông già bị ngã ở cầu thang.","fa":"پیرمرد روی پله ها افتاد."},{"de":"Pass auf, dass du nicht stürzt!","en":"Be careful not to fall!","ru":"Осторожно, не упади!","vi":"Hãy cẩn thận để không bị ngã!","fa":"مراقب باشید زمین نخورید!"}]},{"word":"die Subtraktion","en":"subtraction","ru":"вычитание","vi":"phép trừ","fa":"تفریق","examples":[{"de":"Die Subtraktion ist das Gegenteil der Addition.","en":"Subtraction is the opposite of addition.","ru":"Вычитание — противоположность сложения.","vi":"Phép trừ là đối nghịch của phép cộng.","fa":"تفریق مخالف جمع است."},{"de":"Bei der Subtraktion zieht man eine Zahl von einer anderen ab.","en":"In subtraction you take one number away from another.","ru":"При вычитании одно число отнимают от другого.","vi":"Phép trừ liên quan đến việc trừ một số từ một số khác.","fa":"تفریق شامل تفریق یک عدد از عدد دیگر است."},{"de":"Die Subtraktion von 10 minus 4 ergibt 6.","en":"The subtraction of 10 minus 4 gives 6.","ru":"Вычитание 10 минус 4 даёт 6.","vi":"Trừ 10 trừ 4 bằng 6.","fa":"تفریق 10 منهای 4 برابر با 6 است."}]},{"word":"suchen","en":"to look for, to search","ru":"искать","vi":"tìm kiếm","fa":"جستجو کنید","examples":[{"de":"Ich suche meinen Schlüssel.","en":"I am looking for my key.","ru":"Я ищу свой ключ.","vi":"Tôi đang tìm chìa khóa của mình.","fa":"من دنبال کلیدم هستم"},{"de":"Wir suchen eine neue Wohnung.","en":"We are looking for a new apartment.","ru":"Мы ищем новую квартиру.","vi":"Chúng tôi đang tìm kiếm một căn hộ mới.","fa":"ما به دنبال یک آپارتمان جدید هستیم."}]},{"word":"die Suchmaschine","en":"search engine","ru":"поисковая система, поисковик","vi":"công cụ tìm kiếm","fa":"موتور جستجو","examples":[{"de":"Gib den Begriff einfach in die Suchmaschine ein.","en":"Just type the term into the search engine.","ru":"Просто введи запрос в поисковую систему.","vi":"Đơn giản chỉ cần nhập thuật ngữ vào công cụ tìm kiếm.","fa":"به سادگی عبارت را در موتور جستجو وارد کنید."},{"de":"Diese Suchmaschine speichert keine persönlichen Daten.","en":"This search engine doesn't store any personal data.","ru":"Эта поисковая система не сохраняет личные данные.","vi":"Công cụ tìm kiếm này không lưu trữ bất kỳ dữ liệu cá nhân nào.","fa":"این موتور جستجو هیچ اطلاعات شخصی را ذخیره نمی کند."},{"de":"Die Suchmaschine liefert tausende Ergebnisse.","en":"The search engine returns thousands of results.","ru":"Поисковая система выдаёт тысячи результатов.","vi":"Công cụ tìm kiếm cung cấp hàng ngàn kết quả.","fa":"موتور جستجو هزاران نتیجه را ارائه می دهد."}]},{"word":"die Sucht","en":"addiction","ru":"зависимость","vi":"sự nghiện ngập","fa":"اعتیاد","examples":[{"de":"Seine Sucht nach Zigaretten war schwer zu besiegen.","en":"His addiction to cigarettes was hard to overcome.","ru":"Его зависимость от сигарет было трудно преодолеть.","vi":"Chứng nghiện thuốc lá của anh rất khó vượt qua.","fa":"غلبه بر اعتیاد او به سیگار دشوار بود."},{"de":"Die Ärzte warnen vor der Sucht nach dem Handy.","en":"Doctors warn about smartphone addiction.","ru":"Врачи предупреждают о зависимости от смартфона.","vi":"Các bác sĩ cảnh báo chống nghiện điện thoại di động.","fa":"هشدار پزشکان نسبت به اعتیاد به تلفن همراه"}]},{"word":"süchtig","en":"addicted","ru":"зависимый (от чего-либо)","vi":"nghiện","fa":"معتاد","examples":[{"de":"Viele Jugendliche sind süchtig nach ihrem Handy.","en":"Many teenagers are addicted to their phones.","ru":"Многие подростки зависимы от своего телефона.","vi":"Nhiều bạn trẻ nghiện điện thoại di động.","fa":"بسیاری از جوانان به تلفن همراه خود معتاد هستند."},{"de":"Er wurde süchtig nach Computerspielen.","en":"He became addicted to computer games.","ru":"Он стал зависимым от компьютерных игр.","vi":"Anh ấy trở nên nghiện trò chơi máy tính.","fa":"او به بازی های رایانه ای معتاد شد."},{"de":"Sie ist regelrecht süchtig nach Schokolade.","en":"She's downright addicted to chocolate.","ru":"Она буквально зависима от шоколада.","vi":"Cô ấy thực sự nghiện sô cô la.","fa":"او به معنای واقعی کلمه به شکلات معتاد است."}]},{"word":"das Suchtmittel","en":"addictive substance, intoxicant","ru":"вызывающее зависимость вещество, наркотическое средство","vi":"chất gây nghiện","fa":"ماده اعتیاد آور","examples":[{"de":"Alkohol ist ein gefährliches Suchtmittel.","en":"Alcohol is a dangerous addictive substance.","ru":"Алкоголь — опасное вызывающее зависимость вещество.","vi":"Rượu là một chất gây nghiện nguy hiểm.","fa":"الکل یک ماده اعتیاد آور خطرناک است."},{"de":"Der Verkauf solcher Suchtmittel ist verboten.","en":"The sale of such addictive substances is forbidden.","ru":"Продажа таких веществ запрещена.","vi":"Việc bán các chất gây nghiện như vậy đều bị cấm.","fa":"فروش این گونه مواد اعتیاد آور ممنوع است."},{"de":"In der Beratungsstelle spricht man über den Umgang mit Suchtmitteln.","en":"At the counselling centre people talk about dealing with addictive substances.","ru":"В консультационном центре говорят о том, как обращаться с такими веществами.","vi":"Tại trung tâm tư vấn, chúng tôi nói về việc xử lý các chất gây nghiện.","fa":"در مرکز مشاوره در مورد مقابله با مواد اعتیاد آور صحبت می کنیم."}]},{"word":"die Summe","en":"sum, total amount","ru":"сумма","vi":"tổng","fa":"مجموع","examples":[{"de":"Die Summe aller Kosten beträgt tausend Euro.","en":"The sum of all costs amounts to a thousand euros.","ru":"Сумма всех расходов составляет тысячу евро.","vi":"Tổng cộng tất cả các chi phí là một nghìn euro.","fa":"مجموع تمام هزینه ها هزار یورو است."},{"de":"Er hat eine hohe Summe gespart.","en":"He has saved a large sum.","ru":"Он накопил большую сумму.","vi":"Anh ấy đã tiết kiệm được một khoản tiền lớn.","fa":"او مبلغ زیادی پس انداز کرده است."}]},{"word":"super","en":"great, super","ru":"супер, отлично","vi":"tuyệt vời","fa":"عالی","examples":[{"de":"Der Film war super!","en":"The movie was great!","ru":"Фильм был супер!","vi":"Bộ phim thật tuyệt vời!","fa":"فیلم عالی بود!"},{"de":"Das hast du super gemacht.","en":"You did that great.","ru":"Ты сделал это отлично.","vi":"Bạn đã làm rất tốt.","fa":"عالی کار کردی"}]},{"word":"der Supermarkt","en":"supermarket","ru":"супермаркет","vi":"siêu thị","fa":"سوپرمارکت","examples":[{"de":"Ich kaufe im Supermarkt ein.","en":"I shop at the supermarket.","ru":"Я делаю покупки в супермаркете.","vi":"Tôi mua sắm ở siêu thị.","fa":"من از سوپرمارکت خرید می کنم."},{"de":"Der Supermarkt hat bis 20 Uhr geöffnet.","en":"The supermarket is open until 8 p.m.","ru":"Супермаркет открыт до 20 часов.","vi":"Siêu thị mở cửa đến 8 giờ tối.","fa":"سوپرمارکت تا ساعت 8 شب باز است."}]},{"word":"die Suppe","en":"soup","ru":"суп","vi":"súp","fa":"سوپ","examples":[{"de":"Meine Mutter kocht eine leckere Suppe.","en":"My mother is cooking a delicious soup.","ru":"Моя мама варит вкусный суп.","vi":"Mẹ tôi nấu một món súp ngon.","fa":"مادرم یک سوپ خوشمزه درست می کند."},{"de":"Ich esse gern Suppe im Winter.","en":"I like to eat soup in winter.","ru":"Я люблю есть суп зимой.","vi":"Tôi thích ăn súp vào mùa đông.","fa":"من دوست دارم در زمستان سوپ بخورم."}]},{"word":"süß","en":"sweet; cute","ru":"сладкий; милый","vi":"ngọt ngào","fa":"شیرین","examples":[{"de":"Der Kuchen ist sehr süß.","en":"The cake is very sweet.","ru":"Торт очень сладкий.","vi":"Bánh rất ngọt.","fa":"کیک خیلی شیرینه"},{"de":"Das kleine Kätzchen ist so süß!","en":"The little kitten is so cute!","ru":"Этот маленький котёнок такой милый!","vi":"Con mèo nhỏ đáng yêu quá!","fa":"بچه گربه کوچولو خیلی بامزه است!"}]},{"word":"das Symbol","en":"symbol","ru":"символ","vi":"biểu tượng","fa":"نماد","examples":[{"de":"Die Taube ist ein Symbol für Frieden.","en":"The dove is a symbol of peace.","ru":"Голубь — символ мира.","vi":"Chim bồ câu là biểu tượng của hòa bình.","fa":"کبوتر نماد صلح است."},{"de":"Auf dem Bildschirm siehst du ein neues Symbol.","en":"You see a new symbol on the screen.","ru":"На экране ты видишь новый значок.","vi":"Bạn sẽ thấy một biểu tượng mới trên màn hình.","fa":"یک نماد جدید روی صفحه نمایش خواهید دید."}]},{"word":"sympathisch","en":"likeable, nice","ru":"симпатичный, приятный","vi":"thông cảm","fa":"دلسوز","examples":[{"de":"Meine neue Kollegin ist sehr sympathisch.","en":"My new colleague is very likeable.","ru":"Моя новая коллега очень приятная.","vi":"Đồng nghiệp mới của tôi rất dễ mến.","fa":"همکار جدید من خیلی دوست داشتنی است."},{"de":"Er wirkt auf mich sympathisch.","en":"He seems likeable to me.","ru":"Он производит на меня приятное впечатление.","vi":"Anh ấy có vẻ dễ mến đối với tôi.","fa":"او برای من دوست داشتنی به نظر می رسد."}]},{"word":"das System","en":"system","ru":"система","vi":"hệ thống","fa":"سیستم","examples":[{"de":"Das politische System hat sich verändert.","en":"The political system has changed.","ru":"Политическая система изменилась.","vi":"Hệ thống chính trị đã thay đổi.","fa":"نظام سیاسی تغییر کرده است."},{"de":"Unser Computer hat ein neues System.","en":"Our computer has a new system.","ru":"У нашего компьютера новая система.","vi":"Máy tính của chúng tôi có một hệ thống mới.","fa":"کامپیوتر ما یک سیستم جدید دارد."}]},{"word":"die Szene","en":"scene","ru":"сцена, эпизод","vi":"bối cảnh","fa":"صحنه","examples":[{"de":"Diese Szene im Film hat mich sehr berührt.","en":"This scene in the movie touched me a lot.","ru":"Эта сцена в фильме меня очень тронула.","vi":"Cảnh này trong phim thực sự làm tôi cảm động.","fa":"این صحنه در فیلم واقعاً مرا تحت تأثیر قرار داد."},{"de":"Die Schauspieler proben die letzte Szene.","en":"The actors are rehearsing the last scene.","ru":"Актёры репетируют последнюю сцену.","vi":"Các diễn viên diễn tập cảnh cuối cùng.","fa":"بازیگران صحنه پایانی را تمرین می کنند."}]},{"word":"die Tabelle","en":"table, chart","ru":"таблица","vi":"cái bàn","fa":"جدول","examples":[{"de":"Die Ergebnisse stehen in der Tabelle.","en":"The results are in the table.","ru":"Результаты указаны в таблице.","vi":"Kết quả có trong bảng.","fa":"نتایج در جدول آمده است."},{"de":"Er trägt die Zahlen in eine Tabelle ein.","en":"He enters the numbers into a table.","ru":"Он вносит числа в таблицу.","vi":"Anh ta nhập các số vào một bảng.","fa":"او اعداد را در جدول وارد می کند."}]},{"word":"die Tablette","en":"pill, tablet","ru":"таблетка","vi":"máy tính bảng","fa":"تبلت","examples":[{"de":"Nimm diese Tablette gegen die Kopfschmerzen.","en":"Take this pill for the headache.","ru":"Прими эту таблетку от головной боли.","vi":"Dùng máy tính bảng này để giảm đau đầu.","fa":"این قرص را برای سردرد مصرف کنید."},{"de":"Der Arzt hat mir Tabletten verschrieben.","en":"The doctor prescribed me pills.","ru":"Врач прописал мне таблетки.","vi":"Bác sĩ kê cho tôi thuốc viên.","fa":"دکتر برام قرص تجویز کرد."}]},{"word":"die Tafel","en":"blackboard; bar (of chocolate)","ru":"доска; плитка (шоколада)","vi":"bảng","fa":"تخته (سیاه)","examples":[{"de":"Der Lehrer schreibt die Wörter an die Tafel.","en":"The teacher writes the words on the blackboard.","ru":"Учитель пишет слова на доске.","vi":"Giáo viên viết các từ lên bảng.","fa":"معلم کلمات را روی تخته می نویسد."},{"de":"Ich habe eine Tafel Schokolade gekauft.","en":"I bought a bar of chocolate.","ru":"Я купил плитку шоколада.","vi":"Tôi đã mua một thanh sô cô la.","fa":"من یک تخته شکلات خریدم."}]},{"word":"der Tagesablauf","en":"daily routine","ru":"распорядок дня","vi":"thói quen hàng ngày","fa":"روال روزانه","examples":[{"de":"Mein Tagesablauf beginnt um sechs Uhr.","en":"My daily routine starts at six o'clock.","ru":"Мой распорядок дня начинается в шесть часов.","vi":"Công việc hàng ngày của tôi bắt đầu lúc sáu giờ.","fa":"برنامه روزانه من از ساعت شش شروع می شود."},{"de":"Der Tagesablauf im Kindergarten ist gut organisiert.","en":"The daily routine in the kindergarten is well organized.","ru":"Распорядок дня в детском саду хорошо организован.","vi":"Thói quen hàng ngày ở trường mẫu giáo được tổ chức tốt.","fa":"برنامه روزانه در مهدکودک به خوبی سازماندهی شده است."}]},{"word":"der Tagesausflug","en":"day trip","ru":"однодневная поездка, экскурсия на день","vi":"chuyến đi trong ngày","fa":"سفر یک روزه","examples":[{"de":"Am Sonntag machen wir einen Tagesausflug an den See.","en":"On Sunday we are going on a day trip to the lake.","ru":"В воскресенье мы едем на однодневную экскурсию к озеру.","vi":"Vào chủ nhật chúng tôi có một chuyến đi trong ngày đến hồ.","fa":"یکشنبه یک سفر یک روزه به دریاچه داریم."},{"de":"Der Tagesausflug in die Berge war ein voller Erfolg.","en":"The day trip to the mountains was a complete success.","ru":"Однодневная поездка в горы прошла с большим успехом.","vi":"Chuyến đi trong ngày lên núi đã thành công trọn vẹn.","fa":"سفر یک روزه به کوهستان با موفقیت کامل همراه بود."},{"de":"Für den Tagesausflug brauchst du keine schwere Tasche.","en":"For the day trip you do not need a heavy bag.","ru":"Для однодневной поездки тебе не нужна тяжёлая сумка.","vi":"Bạn không cần một chiếc túi nặng nề cho chuyến đi trong ngày.","fa":"برای سفر یک روزه نیازی به کیف سنگین ندارید."}]},{"word":"das Tal","en":"valley","ru":"долина","vi":"thung lũng","fa":"دره","examples":[{"de":"Das Dorf liegt in einem schönen Tal.","en":"The village lies in a beautiful valley.","ru":"Деревня расположена в красивой долине.","vi":"Ngôi làng nằm trong một thung lũng xinh đẹp.","fa":"این روستا در دره ای زیبا واقع شده است."},{"de":"Wir wanderten durch das grüne Tal.","en":"We hiked through the green valley.","ru":"Мы шли пешком по зелёной долине.","vi":"Chúng tôi đi bộ qua thung lũng xanh.","fa":"از میان دره سرسبز پیاده روی کردیم."}]},{"word":"das Talent","en":"talent","ru":"талант","vi":"tài năng","fa":"استعداد","examples":[{"de":"Sie hat ein großes Talent für Musik.","en":"She has a great talent for music.","ru":"У неё большой талант к музыке.","vi":"Cô ấy có năng khiếu âm nhạc tuyệt vời.","fa":"او استعداد زیادی در موسیقی دارد."},{"de":"Er zeigt schon als Kind sein Talent.","en":"He already shows his talent as a child.","ru":"Он проявляет свой талант уже в детстве.","vi":"Anh ấy thể hiện tài năng của mình ngay cả khi còn nhỏ.","fa":"او حتی در کودکی استعداد خود را نشان می دهد."}]},{"word":"die Talkshow","en":"talk show, chat show","ru":"ток-шоу","vi":"chương trình trò chuyện","fa":"برنامه گفتگو","examples":[{"de":"Gestern Abend lief eine interessante Talkshow im Fernsehen.","en":"Last night there was an interesting talk show on television.","ru":"Вчера вечером по телевизору было интересное ток-шоу.","vi":"Một chương trình trò chuyện thú vị đã được chiếu trên TV tối qua.","fa":"دیشب یک برنامه گفتگوی جالب از تلویزیون پخش شد."},{"de":"In der Talkshow ging es um das Thema Klimaschutz.","en":"The talk show was about the subject of climate protection.","ru":"Ток-шоу было посвящено теме защиты климата.","vi":"Buổi tọa đàm xoay quanh chủ đề bảo vệ khí hậu.","fa":"برنامه گفتگو با موضوع حفاظت از آب و هوا بود."},{"de":"Der Politiker war zu Gast in einer Talkshow.","en":"The politician was a guest on a talk show.","ru":"Политик был гостем ток-шоу.","vi":"Chính trị gia này là khách mời trong một chương trình trò chuyện.","fa":"این سیاستمدار مهمان یک برنامه گفتگو بود."}]},{"word":"der Tango","en":"tango","ru":"танго","vi":"tango","fa":"تانگو","examples":[{"de":"Der Tango stammt ursprünglich aus Argentinien.","en":"The tango originally comes from Argentina.","ru":"Танго изначально родом из Аргентины.","vi":"Tango có nguồn gốc từ Argentina.","fa":"تانگو در اصل از آرژانتین می آید."},{"de":"Beim Tango ist die Verbindung zwischen den Partnern entscheidend.","en":"In the tango the connection between the partners is crucial.","ru":"В танго решающее значение имеет связь между партнёрами.","vi":"Trong tango, sự kết nối giữa các đối tác là rất quan trọng.","fa":"در تانگو، ارتباط بین شرکا بسیار مهم است."},{"de":"Sie tanzten einen leidenschaftlichen Tango.","en":"They danced a passionate tango.","ru":"Они станцевали страстное танго.","vi":"Họ nhảy một điệu tango đầy đam mê.","fa":"آنها یک تانگو پرشور رقصیدند."}]},{"word":"tanken","en":"to fill up (with fuel)","ru":"заправляться (топливом)","vi":"tiếp nhiên liệu","fa":"سوخت گیری","examples":[{"de":"Wir müssen noch tanken, bevor wir losfahren.","en":"We still need to fill up before we leave.","ru":"Нам нужно заправиться, прежде чем ехать.","vi":"Chúng tôi vẫn phải tiếp nhiên liệu trước khi khởi hành.","fa":"هنوز باید قبل از حرکت بنزین بزنیم."},{"de":"Er tankt sein Auto an der Tankstelle.","en":"He fills up his car at the gas station.","ru":"Он заправляет машину на заправке.","vi":"Anh ta đổ đầy xe ở trạm xăng.","fa":"ماشینش را در پمپ بنزین پر می کند."}]},{"word":"die Tankstelle","en":"petrol station","ru":"заправочная станция, автозаправка","vi":"trạm xăng","fa":"پمپ بنزین","examples":[{"de":"Wir müssen an der nächsten Tankstelle anhalten.","en":"We need to stop at the next petrol station.","ru":"Нам нужно остановиться на следующей заправке.","vi":"Chúng ta phải dừng lại ở trạm xăng tiếp theo.","fa":"باید در پمپ بنزین بعدی توقف کنیم."},{"de":"Die Tankstelle hat rund um die Uhr geöffnet.","en":"The petrol station is open around the clock.","ru":"Заправка работает круглосуточно.","vi":"Trạm xăng mở cửa suốt ngày đêm.","fa":"پمپ بنزین به صورت شبانه روزی باز است."},{"de":"An der Tankstelle kann man auch Snacks kaufen.","en":"At the petrol station you can also buy snacks.","ru":"На заправке можно также купить перекус.","vi":"Bạn cũng có thể mua đồ ăn nhẹ ở trạm xăng.","fa":"از پمپ بنزین هم می توانید تنقلات بخرید."}]},{"word":"die Tante","en":"aunt","ru":"тётя","vi":"dì","fa":"عمه","examples":[{"de":"Meine Tante wohnt in Berlin.","en":"My aunt lives in Berlin.","ru":"Моя тётя живёт в Берлине.","vi":"Dì tôi sống ở Berlin.","fa":"عمه من در برلین زندگی می کند."},{"de":"Ich besuche meine Tante jedes Jahr.","en":"I visit my aunt every year.","ru":"Я навещаю свою тётю каждый год.","vi":"Tôi đến thăm dì của tôi hàng năm.","fa":"من هر سال به عمه ام سر می زنم."}]},{"word":"die Tanzaufführung","en":"dance performance","ru":"танцевальное выступление","vi":"buổi biểu diễn khiêu vũ","fa":"اجرای رقص","examples":[{"de":"Die Tanzaufführung am Samstag war ausverkauft.","en":"The dance performance on Saturday was sold out.","ru":"Танцевальное выступление в субботу было распродано.","vi":"Buổi biểu diễn khiêu vũ vào thứ bảy đã bán hết vé.","fa":"اجرای رقص روز شنبه به فروش رسید."},{"de":"Für die Tanzaufführung haben wir wochenlang geübt.","en":"We practised for weeks for the dance performance.","ru":"Для танцевального выступления мы репетировали неделями.","vi":"Chúng tôi đã luyện tập hàng tuần cho buổi biểu diễn khiêu vũ.","fa":"هفته ها برای اجرای رقص تمرین کردیم."},{"de":"Nach der Tanzaufführung gab es viel Applaus.","en":"After the dance performance there was much applause.","ru":"После танцевального выступления было много аплодисментов.","vi":"Có rất nhiều tiếng vỗ tay sau màn trình diễn múa.","fa":"پس از اجرای رقص تشویق های زیادی به راه افتاد."}]},{"word":"der Tanzauftritt","en":"dance performance","ru":"танцевальное выступление","vi":"buổi biểu diễn khiêu vũ","fa":"اجرای رقص","examples":[{"de":"Vor dem Tanzauftritt war sie sehr nervös.","en":"Before the dance performance she was very nervous.","ru":"Перед танцевальным выступлением она очень волновалась.","vi":"Cô ấy rất hồi hộp trước màn biểu diễn múa.","fa":"او قبل از اجرای رقص بسیار عصبی بود."},{"de":"Der Tanzauftritt der Kinder begeisterte das Publikum.","en":"The children's dance performance delighted the audience.","ru":"Танцевальное выступление детей привело публику в восторг.","vi":"Tiết mục múa thiếu nhi khiến khán giả thích thú.","fa":"اجرای رقص بچه ها حضار را به وجد آورد."},{"de":"Wir haben wochenlang für diesen Tanzauftritt geprobt.","en":"We rehearsed for weeks for this dance performance.","ru":"Мы неделями репетировали это танцевальное выступление.","vi":"Chúng tôi đã luyện tập cho buổi biểu diễn khiêu vũ này trong nhiều tuần.","fa":"هفته ها برای این اجرای رقص تمرین کردیم."}]},{"word":"tanzen","en":"to dance","ru":"танцевать","vi":"khiêu vũ","fa":"رقصیدن","examples":[{"de":"Wir tanzen gern auf Partys.","en":"We like to dance at parties.","ru":"Мы любим танцевать на вечеринках.","vi":"Chúng tôi thích khiêu vũ ở các bữa tiệc.","fa":"ما رقصیدن در مهمانی ها را دوست داریم."},{"de":"Sie tanzt seit zehn Jahren Ballett.","en":"She has been dancing ballet for ten years.","ru":"Она танцует балет уже десять лет.","vi":"Cô ấy đã nhảy múa ba lê được mười năm.","fa":"او ده سال است که باله می رقصد."}]},{"word":"die Tanzfläche","en":"dance floor","ru":"танцпол, танцевальная площадка","vi":"sàn nhảy","fa":"زمین رقص","examples":[{"de":"Auf der Tanzfläche war kaum noch Platz.","en":"There was hardly any room left on the dance floor.","ru":"На танцполе почти не осталось места.","vi":"Hầu như không còn chỗ trống trên sàn nhảy.","fa":"تقریباً فضایی روی زمین رقص باقی نمانده بود."},{"de":"Wir gingen sofort auf die Tanzfläche, als die Musik begann.","en":"We went straight onto the dance floor when the music started.","ru":"Мы сразу вышли на танцпол, как только заиграла музыка.","vi":"Chúng tôi ngay lập tức đi đến sàn nhảy khi âm nhạc bắt đầu.","fa":"وقتی موسیقی شروع شد بلافاصله به پیست رقص رفتیم."},{"de":"Die Tanzfläche leuchtete in verschiedenen Farben.","en":"The dance floor lit up in different colours.","ru":"Танцпол засветился разными цветами.","vi":"Sàn nhảy bừng sáng với nhiều màu sắc khác nhau.","fa":"زمین رقص به رنگ های مختلف روشن شد."}]},{"word":"das Tanzlokal","en":"dance hall, dance venue","ru":"танцевальный зал, танцевальное заведение","vi":"vũ trường","fa":"سالن رقص","examples":[{"de":"Am Wochenende gehen wir gern in ein Tanzlokal.","en":"At the weekend we like to go to a dance hall.","ru":"По выходным мы любим ходить в танцевальный зал.","vi":"Vào cuối tuần chúng tôi thích đi đến vũ trường.","fa":"آخر هفته دوست داریم به سالن رقص برویم."},{"de":"Das Tanzlokal war bis spät in die Nacht geöffnet.","en":"The dance hall was open until late at night.","ru":"Танцевальный зал был открыт до поздней ночи.","vi":"Vũ trường mở cửa đến khuya.","fa":"سالن رقص تا پاسی از شب باز بود."},{"de":"In diesem Tanzlokal spielt jeden Samstag eine Live-Band.","en":"A live band plays in this dance hall every Saturday.","ru":"Каждую субботу в этом заведении играет живая группа.","vi":"Một ban nhạc sống biểu diễn ở vũ trường này vào thứ Bảy hàng tuần.","fa":"هر شنبه یک گروه موسیقی زنده در این سالن رقص اجرا می کند."}]},{"word":"das Tanzpaar","en":"dancing couple","ru":"танцевальная пара","vi":"cặp đôi khiêu vũ","fa":"زوج رقصنده","examples":[{"de":"Das Tanzpaar gewann den ersten Preis im Wettbewerb.","en":"The dancing couple won first prize in the competition.","ru":"Танцевальная пара заняла первое место на конкурсе.","vi":"Cặp đôi nhảy đã giành giải nhất trong cuộc thi.","fa":"این زوج رقصنده جایزه اول مسابقه را به دست آوردند."},{"de":"Ein erfahrenes Tanzpaar bewegt sich wie eine Einheit.","en":"An experienced dancing couple moves as one.","ru":"Опытная танцевальная пара движется как единое целое.","vi":"Một cặp đôi khiêu vũ có kinh nghiệm di chuyển như một.","fa":"یک زوج رقصنده با تجربه به عنوان یک نفر حرکت می کنند."},{"de":"Auf dem Ball trat jedes Tanzpaar einzeln auf.","en":"At the ball each dancing couple performed individually.","ru":"На балу каждая танцевальная пара выступала отдельно.","vi":"Tại vũ hội, mỗi cặp nhảy biểu diễn riêng lẻ.","fa":"در رقص، هر زوج رقص به صورت جداگانه اجرا کردند."}]},{"word":"der Tanzpartner","en":"dance partner","ru":"партнёр по танцу","vi":"bạn nhảy","fa":"شریک رقص","examples":[{"de":"Ohne einen guten Tanzpartner macht das Tanzen weniger Spaß.","en":"Without a good dance partner, dancing is less fun.","ru":"Без хорошего партнёра по танцу танцевать менее интересно.","vi":"Khiêu vũ sẽ kém vui hơn nếu không có bạn nhảy giỏi.","fa":"رقصیدن بدون یک شریک رقص خوب کمتر سرگرم کننده است."},{"de":"Sie suchte einen Tanzpartner für das Turnier.","en":"She was looking for a dance partner for the tournament.","ru":"Она искала партнёра по танцу для турнира.","vi":"Cô ấy đang tìm kiếm một bạn nhảy cho giải đấu.","fa":"او به دنبال یک شریک رقص برای مسابقات بود."},{"de":"Mein Tanzpartner führt sehr sicher und ruhig.","en":"My dance partner leads very confidently and calmly.","ru":"Мой партнёр по танцу ведёт очень уверенно и спокойно.","vi":"Bạn nhảy của tôi dẫn đầu rất an toàn và bình tĩnh.","fa":"شریک رقص من بسیار ایمن و آرام رهبری می کند."}]},{"word":"das Tanztheater","en":"dance theatre","ru":"танцевальный театр (театр танца)","vi":"nhà hát khiêu vũ","fa":"تئاتر رقص","examples":[{"de":"Wir gehen heute Abend ins Tanztheater.","en":"We are going to the dance theatre this evening.","ru":"Сегодня вечером мы идём в танцевальный театр.","vi":"Tối nay chúng ta sẽ đến nhà hát khiêu vũ.","fa":"امشب به رقص تئاتر می رویم."},{"de":"Das Tanztheater verbindet Bewegung und Schauspiel.","en":"Dance theatre combines movement and acting.","ru":"Танцевальный театр соединяет движение и актёрскую игру.","vi":"Sân khấu múa kết hợp chuyển động và diễn xuất.","fa":"رقص تئاتر ترکیبی از حرکت و بازیگری است."},{"de":"Sie tanzt seit Jahren in einem modernen Tanztheater.","en":"She has danced in a modern dance theatre for years.","ru":"Она уже много лет танцует в современном танцевальном театре.","vi":"Cô ấy đã nhảy trong một nhà hát múa hiện đại trong nhiều năm.","fa":"او سالهاست که در یک تئاتر رقص مدرن می رقصد."}]},{"word":"die Tanzvorführung","en":"dance performance","ru":"танцевальное выступление, показательный танец","vi":"buổi biểu diễn khiêu vũ","fa":"اجرای رقص","examples":[{"de":"Die Tanzvorführung begeisterte das ganze Publikum.","en":"The dance performance delighted the entire audience.","ru":"Танцевальное выступление привело в восторг всю публику.","vi":"Màn múa làm rung động toàn bộ khán giả.","fa":"اجرای رقص تمام حضار را به وجد آورد."},{"de":"Für die Tanzvorführung haben wir wochenlang geübt.","en":"We practised for weeks for the dance performance.","ru":"К танцевальному выступлению мы репетировали неделями.","vi":"Chúng tôi đã luyện tập hàng tuần cho buổi biểu diễn khiêu vũ.","fa":"هفته ها برای اجرای رقص تمرین کردیم."},{"de":"Am Ende der Tanzvorführung gab es großen Applaus.","en":"There was loud applause at the end of the dance performance.","ru":"В конце танцевального выступления были громкие аплодисменты.","vi":"Kết thúc màn múa là những tràng pháo tay vang dội.","fa":"در پایان اجرای رقص تشویق شدیدی به همراه داشت."}]},{"word":"die Tasche","en":"bag","ru":"сумка","vi":"cái túi","fa":"کیف","examples":[{"de":"Ich habe meine Tasche im Bus vergessen.","en":"I forgot my bag on the bus.","ru":"Я забыл свою сумку в автобусе.","vi":"Tôi quên túi trên xe buýt.","fa":"کیفم را در اتوبوس فراموش کردم."},{"de":"In der Tasche sind meine Bücher.","en":"My books are in the bag.","ru":"В сумке лежат мои книги.","vi":"Sách của tôi ở trong túi.","fa":"کتاب های من در کیف است."}]},{"word":"das Taschengeld","en":"pocket money, allowance","ru":"карманные деньги","vi":"tiền tiêu vặt","fa":"پول جیبی","examples":[{"de":"Die Kinder bekommen jede Woche Taschengeld.","en":"The children get pocket money every week.","ru":"Дети получают карманные деньги каждую неделю.","vi":"Trẻ em được nhận tiền tiêu vặt hàng tuần.","fa":"بچه ها هر هفته پول تو جیبی می گیرند."},{"de":"Er spart sein Taschengeld für ein neues Fahrrad.","en":"He saves his pocket money for a new bike.","ru":"Он копит карманные деньги на новый велосипед.","vi":"Anh ấy tiết kiệm tiền tiêu vặt để mua một chiếc xe đạp mới.","fa":"او پول جیبی خود را برای یک دوچرخه جدید پس انداز می کند."}]},{"word":"das Taschentuch","en":"handkerchief, tissue","ru":"носовой платок, салфетка","vi":"chiếc khăn tay","fa":"دستمال","examples":[{"de":"Hast du ein Taschentuch für mich?","en":"Do you have a tissue for me?","ru":"У тебя есть для меня платок?","vi":"Bạn có khăn giấy cho tôi không?","fa":"دستمال کاغذی برای من داری؟"},{"de":"Sie putzt sich die Nase mit einem Taschentuch.","en":"She blows her nose with a tissue.","ru":"Она вытирает нос платком.","vi":"Cô ấy xì mũi bằng khăn giấy.","fa":"بینی اش را با دستمال باد می کند."}]},{"word":"die Tasse","en":"cup","ru":"чашка","vi":"cái cốc","fa":"فنجان","examples":[{"de":"Ich trinke eine Tasse Kaffee zum Frühstück.","en":"I drink a cup of coffee for breakfast.","ru":"Я пью чашку кофе на завтрак.","vi":"Tôi uống một tách cà phê cho bữa sáng.","fa":"برای صبحانه یک فنجان قهوه می نوشم."},{"de":"Kannst du mir eine Tasse Tee machen?","en":"Can you make me a cup of tea?","ru":"Можешь сделать мне чашку чая?","vi":"Bạn có thể pha cho tôi một tách trà được không?","fa":"میشه یه فنجان چای برام درست کنی؟"}]},{"word":"die Tastatur","en":"keyboard","ru":"клавиатура","vi":"bàn phím","fa":"صفحه کلید","examples":[{"de":"Meine Tastatur funktioniert nicht mehr richtig.","en":"My keyboard no longer works properly.","ru":"Моя клавиатура больше не работает как следует.","vi":"Bàn phím của tôi không còn hoạt động bình thường nữa.","fa":"صفحه کلید من دیگر درست کار نمی کند."},{"de":"Er tippt sehr schnell auf der Tastatur.","en":"He types very fast on the keyboard.","ru":"Он очень быстро печатает на клавиатуре.","vi":"Anh ấy gõ bàn phím rất nhanh.","fa":"او خیلی سریع روی صفحه کلید تایپ می کند."}]},{"word":"die Taste","en":"key, button","ru":"клавиша, кнопка","vi":"cái nút","fa":"دکمه","examples":[{"de":"Drück die grüne Taste, um anzurufen.","en":"Press the green button to call.","ru":"Нажми зелёную кнопку, чтобы позвонить.","vi":"Nhấn nút xanh để gọi.","fa":"برای تماس دکمه سبز رنگ را فشار دهید."},{"de":"Diese Taste auf der Tastatur ist kaputt.","en":"This key on the keyboard is broken.","ru":"Эта клавиша на клавиатуре сломана.","vi":"Phím này trên bàn phím bị hỏng.","fa":"این کلید روی کیبورد خراب است."}]},{"word":"die Tat","en":"act, deed","ru":"поступок, деяние","vi":"hành động","fa":"عمل","examples":[{"de":"Das war eine mutige Tat.","en":"That was a brave deed.","ru":"Это был смелый поступок.","vi":"Đó là một hành động dũng cảm.","fa":"این یک اقدام شجاعانه بود."},{"de":"Er wurde für seine gute Tat belohnt.","en":"He was rewarded for his good deed.","ru":"Его наградили за его добрый поступок.","vi":"Anh ấy đã được khen thưởng vì hành động tốt của mình.","fa":"او پاداش عمل نیکش را گرفت."}]},{"word":"der Täter","en":"perpetrator, offender (male)","ru":"преступник, виновник (мужчина)","vi":"thủ phạm","fa":"عامل","examples":[{"de":"Die Polizei konnte den Täter schnell festnehmen.","en":"The police were able to arrest the perpetrator quickly.","ru":"Полиция смогла быстро задержать преступника.","vi":"Cảnh sát đã nhanh chóng bắt giữ thủ phạm.","fa":"پلیس توانست به سرعت عامل جنایت را دستگیر کند."},{"de":"Der Täter hatte keine Zeugen für seine Tat.","en":"The perpetrator had no witnesses for his crime.","ru":"У преступника не было свидетелей его деяния.","vi":"Hung thủ không có nhân chứng cho tội ác của mình.","fa":"عامل جنایت شاهدی برای جنایت خود نداشت."},{"de":"Bisher ist der Täter unbekannt geblieben.","en":"So far the perpetrator has remained unknown.","ru":"Пока преступник остаётся неизвестным.","vi":"Hung thủ cho đến nay vẫn chưa được xác định.","fa":"عامل جنایت تاکنون ناشناس مانده است."}]},{"word":"die Täterin","en":"perpetrator, offender (female)","ru":"преступница, виновница (женщина)","vi":"thủ phạm","fa":"عامل","examples":[{"de":"Die Täterin wurde noch am selben Tag gefasst.","en":"The female perpetrator was caught on the same day.","ru":"Преступницу поймали в тот же день.","vi":"Thủ phạm đã bị bắt ngay trong ngày.","fa":"عامل جنایت در همان روز دستگیر شد."},{"de":"Vor Gericht gestand die Täterin ihre Tat.","en":"In court the female offender confessed to her crime.","ru":"В суде преступница призналась в своём деянии.","vi":"Thủ phạm đã thừa nhận hành vi phạm tội của mình trước tòa.","fa":"عامل جنایت در دادگاه به جرم خود اعتراف کرد."},{"de":"Die Polizei sucht weiterhin nach der Täterin.","en":"The police are still searching for the female perpetrator.","ru":"Полиция всё ещё ищет преступницу.","vi":"Cảnh sát vẫn đang truy tìm thủ phạm.","fa":"پلیس همچنان در جستجوی عامل جنایت است."}]},{"word":"die Tätigkeit","en":"activity, occupation, work","ru":"деятельность, занятие, работа","vi":"hoạt động","fa":"فعالیت","examples":[{"de":"Welche Tätigkeit übst du in deinem Beruf aus?","en":"What activity do you carry out in your job?","ru":"Какую работу ты выполняешь на своей должности?","vi":"Bạn làm hoạt động gì trong công việc của mình?","fa":"چه فعالیتی در شغل خود انجام می دهید؟"},{"de":"Gartenarbeit ist eine entspannende Tätigkeit für mich.","en":"Gardening is a relaxing activity for me.","ru":"Работа в саду — расслабляющее занятие для меня.","vi":"Làm vườn là một hoạt động thư giãn đối với tôi.","fa":"باغبانی برای من یک فعالیت آرامش بخش است."},{"de":"Nach dem Unfall musste er seine berufliche Tätigkeit aufgeben.","en":"After the accident he had to give up his professional occupation.","ru":"После аварии ему пришлось оставить свою профессиональную деятельность.","vi":"Sau tai nạn, anh phải từ bỏ hoạt động nghề nghiệp của mình.","fa":"پس از تصادف مجبور شد فعالیت حرفه ای خود را رها کند."}]},{"word":"die Tatsache","en":"fact","ru":"факт","vi":"sự thật","fa":"واقعیت","examples":[{"de":"Es ist eine Tatsache, dass die Erde rund ist.","en":"It is a fact that the Earth is round.","ru":"Это факт, что Земля круглая.","vi":"Sự thật là trái đất tròn.","fa":"این یک واقعیت است که زمین گرد است."},{"de":"Wir müssen die Tatsachen akzeptieren.","en":"We have to accept the facts.","ru":"Мы должны принять факты.","vi":"Chúng ta phải chấp nhận sự thật.","fa":"ما باید واقعیت ها را بپذیریم."}]},{"word":"tatsächlich","en":"actually; really; indeed","ru":"действительно, на самом деле","vi":"Thực ra","fa":"در واقع","examples":[{"de":"Hast du das tatsächlich allein gemacht?","en":"Did you actually do that on your own?","ru":"Ты действительно сделал это сам?","vi":"Bạn thực sự đã làm điều này một mình?","fa":"واقعا این کار را به تنهایی انجام دادی؟"},{"de":"Er ist tatsächlich pünktlich gekommen.","en":"He really did arrive on time.","ru":"Он и правда пришёл вовремя.","vi":"Thực ra anh ấy đã đến đúng giờ.","fa":"او در واقع به موقع آمد."},{"de":"Das ist die tatsächliche Ursache des Problems.","en":"That is the actual cause of the problem.","ru":"Это и есть настоящая причина проблемы.","vi":"Đó là nguyên nhân thực sự của vấn đề.","fa":"علت واقعی مشکل همین است."}]},{"word":"taub","en":"deaf","ru":"глухой","vi":"điếc","fa":"ناشنوا","examples":[{"de":"Mein Großvater ist auf einem Ohr taub.","en":"My grandfather is deaf in one ear.","ru":"Мой дедушка глухой на одно ухо.","vi":"Ông tôi bị điếc một bên tai.","fa":"پدربزرگ من از یک گوش ناشنوا است."},{"de":"Sie ist von Geburt an taub.","en":"She has been deaf since birth.","ru":"Она глухая с рождения.","vi":"Cô bị điếc từ khi mới sinh ra.","fa":"او از بدو تولد ناشنوا بوده است."}]},{"word":"tauchen","en":"to dive","ru":"нырять","vi":"lặn","fa":"غواصی","examples":[{"de":"Die Kinder tauchen gern im See.","en":"The children like to dive in the lake.","ru":"Дети любят нырять в озере.","vi":"Trẻ em thích thú lặn xuống hồ.","fa":"بچه ها از غواصی در دریاچه لذت می برند."},{"de":"Er hat gelernt, mit Sauerstoffflasche zu tauchen.","en":"He learned to dive with an oxygen tank.","ru":"Он научился нырять с аквалангом.","vi":"Anh ấy đã học cách lặn bằng bình dưỡng khí.","fa":"او یاد گرفت که با مخزن اکسیژن شیرجه بزند."}]},{"word":"tauschen","en":"to exchange, to swap","ru":"обменивать(ся)","vi":"trao đổi","fa":"مبادله","examples":[{"de":"Wir haben unsere Plätze getauscht.","en":"We swapped our seats.","ru":"Мы поменялись местами.","vi":"Chúng tôi đổi chỗ cho nhau.","fa":"جای خود را عوض کردیم."},{"de":"Die Kinder tauschen ihre Sticker.","en":"The children are swapping their stickers.","ru":"Дети обмениваются наклейками.","vi":"Trẻ em trao đổi nhãn dán của mình.","fa":"بچه ها برچسب هایشان را عوض می کنند."}]},{"word":"täuschen","en":"to deceive; to be mistaken (sich täuschen)","ru":"обманывать; заблуждаться (sich täuschen)","vi":"lừa dối","fa":"فریب دادن","examples":[{"de":"Lass dich nicht von ihm täuschen.","en":"Don't let him deceive you.","ru":"Не давай ему себя обмануть.","vi":"Đừng để anh ta đánh lừa bạn.","fa":"اجازه نده او شما را گول بزند."},{"de":"Ich habe mich in ihm getäuscht.","en":"I was mistaken about him.","ru":"Я в нём ошибся.","vi":"Tôi đã sai về anh ấy.","fa":"من در مورد او اشتباه کردم."},{"de":"Der erste Eindruck kann täuschen.","en":"First impressions can be deceptive.","ru":"Первое впечатление может быть обманчивым.","vi":"Ấn tượng đầu tiên có thể lừa dối.","fa":"اولین برداشت ها می تواند فریبنده باشد."}]},{"word":"das Tauwetter","en":"thaw, mild weather","ru":"оттепель","vi":"sự tan băng","fa":"ذوب شدن","examples":[{"de":"Nach Wochen voller Schnee setzte endlich Tauwetter ein.","en":"After weeks of snow a thaw finally set in.","ru":"После недель снега наконец наступила оттепель.","vi":"Sau nhiều tuần tuyết rơi, băng tan cuối cùng cũng bắt đầu.","fa":"پس از هفته ها برف، سرانجام آب شدن آب شروع شد."},{"de":"Beim Tauwetter werden die Straßen oft sehr matschig.","en":"During the thaw the roads often become very muddy.","ru":"Во время оттепели дороги часто становятся очень грязными.","vi":"Khi có băng tan, đường thường trở nên rất lầy lội.","fa":"هنگامی که آب شدن هوا وجود دارد، جاده ها اغلب بسیار گل آلود می شوند."},{"de":"Das Tauwetter ließ den Fluss schnell ansteigen.","en":"The thaw made the river rise quickly.","ru":"Оттепель заставила реку быстро подняться.","vi":"Sự tan băng khiến mực nước sông tăng nhanh.","fa":"ذوب آب باعث بالا آمدن سریع رودخانه شد."}]},{"word":"das Team","en":"team","ru":"команда","vi":"đội","fa":"تیم","examples":[{"de":"Unser Team besteht aus sechs Personen.","en":"Our team consists of six people.","ru":"Наша команда состоит из шести человек.","vi":"Nhóm của chúng tôi bao gồm sáu người.","fa":"تیم ما از شش نفر تشکیل شده است."},{"de":"Im Team arbeitet man oft besser als allein.","en":"You often work better in a team than alone.","ru":"В команде часто работается лучше, чем в одиночку.","vi":"Bạn thường làm việc theo nhóm tốt hơn là làm việc một mình.","fa":"شما اغلب در یک تیم بهتر از تنهایی کار می کنید."},{"de":"Sie leitet ein internationales Team von Ingenieuren.","en":"She leads an international team of engineers.","ru":"Она руководит международной командой инженеров.","vi":"Cô lãnh đạo một nhóm kỹ sư quốc tế.","fa":"او یک تیم بین المللی از مهندسان را رهبری می کند."}]},{"word":"teamfähig","en":"able to work in a team, a team player","ru":"умеющий работать в команде, командный игрок","vi":"cầu thủ đội","fa":"بازیکن تیم","examples":[{"de":"Für diese Stelle musst du teamfähig sein.","en":"For this job you have to be a team player.","ru":"Для этой должности нужно уметь работать в команде.","vi":"Đối với vị trí này, bạn phải là một người có tinh thần đồng đội.","fa":"برای این پست باید یک بازیکن تیمی باشید."},{"de":"Sie ist sehr teamfähig und hilft ihren Kollegen oft.","en":"She is very good at teamwork and often helps her colleagues.","ru":"Она отлично работает в команде и часто помогает коллегам.","vi":"Cô ấy rất có tinh thần đồng đội và thường xuyên giúp đỡ đồng nghiệp.","fa":"او بسیار تیم محور است و اغلب به همکارانش کمک می کند."},{"de":"In der Stellenanzeige steht, dass man teamfähig sein soll.","en":"The job advert says that you should be able to work in a team.","ru":"В объявлении о вакансии сказано, что нужно уметь работать в команде.","vi":"Quảng cáo việc làm nói rằng bạn nên là một người có tinh thần đồng đội.","fa":"در آگهی استخدام آمده است که باید یک بازیکن تیم باشید."}]},{"word":"die Teamfähigkeit","en":"ability to work in a team","ru":"умение работать в команде","vi":"khả năng làm việc theo nhóm","fa":"توانایی کار در یک تیم","examples":[{"de":"Für diese Stelle ist Teamfähigkeit besonders wichtig.","en":"The ability to work in a team is particularly important for this position.","ru":"Для этой должности особенно важно умение работать в команде.","vi":"Làm việc theo nhóm đặc biệt quan trọng đối với vị trí này.","fa":"کار تیمی برای این موقعیت بسیار مهم است."},{"de":"Im Vorstellungsgespräch wurde nach meiner Teamfähigkeit gefragt.","en":"In the interview I was asked about my ability to work in a team.","ru":"На собеседовании меня спросили об умении работать в команде.","vi":"Trong cuộc phỏng vấn, tôi được hỏi về khả năng làm việc nhóm của mình.","fa":"در طول مصاحبه از من در مورد توانایی من برای کار در یک تیم سوال شد."},{"de":"Teamfähigkeit lernt man am besten in der Praxis.","en":"You learn teamwork skills best in practice.","ru":"Работе в команде лучше всего учишься на практике.","vi":"Làm việc nhóm được học tốt nhất trong thực tế.","fa":"کار تیمی به بهترین وجه در عمل آموخته می شود."}]},{"word":"die Technik","en":"technology; technique","ru":"техника; технология","vi":"công nghệ","fa":"تکنولوژی","examples":[{"de":"Die moderne Technik verändert unser Leben.","en":"Modern technology changes our lives.","ru":"Современная техника меняет нашу жизнь.","vi":"Công nghệ hiện đại đang thay đổi cuộc sống của chúng ta.","fa":"تکنولوژی مدرن زندگی ما را تغییر می دهد."},{"de":"Er hat eine gute Technik beim Schwimmen.","en":"He has a good technique in swimming.","ru":"У него хорошая техника плавания.","vi":"Anh ấy có kỹ thuật bơi tốt.","fa":"او تکنیک شنای خوبی دارد."}]},{"word":"technisch","en":"technical","ru":"технический","vi":"kỹ thuật","fa":"فنی","examples":[{"de":"Wir hatten gestern ein technisches Problem mit dem Server.","en":"We had a technical problem with the server yesterday.","ru":"Вчера у нас была техническая проблема с сервером.","vi":"Chúng tôi đã gặp sự cố kỹ thuật với máy chủ ngày hôm qua.","fa":"دیروز مشکل فنی با سرور داشتیم."},{"de":"Aus technischen Gründen fällt der Zug heute aus.","en":"For technical reasons the train is cancelled today.","ru":"По техническим причинам поезд сегодня отменён.","vi":"Vì lý do kỹ thuật, chuyến tàu hôm nay bị hủy.","fa":"به دلایل فنی قطار امروز لغو شد."},{"de":"Er interessiert sich für technische Geräte.","en":"He is interested in technical devices.","ru":"Он интересуется техническими устройствами.","vi":"Anh ấy quan tâm đến các thiết bị kỹ thuật.","fa":"او به وسایل فنی علاقه مند است."}]},{"word":"die Technologie","en":"technology","ru":"технология","vi":"công nghệ","fa":"تکنولوژی","examples":[{"de":"Neue Technologie verändert die Art, wie wir arbeiten.","en":"New technology is changing the way we work.","ru":"Новые технологии меняют то, как мы работаем.","vi":"Công nghệ mới đang thay đổi cách chúng ta làm việc.","fa":"فناوری جدید در حال تغییر روش کار ما است."},{"de":"Ohne moderne Technologie wäre dieser Beruf nicht denkbar.","en":"Without modern technology this profession would be unthinkable.","ru":"Без современных технологий эта профессия была бы немыслима.","vi":"Nếu không có công nghệ hiện đại thì nghề này sẽ không thể tồn tại được.","fa":"بدون تکنولوژی مدرن، این حرفه غیر قابل تصور خواهد بود."},{"de":"Das Krankenhaus investiert in neue medizinische Technologie.","en":"The hospital is investing in new medical technology.","ru":"Больница вкладывает средства в новые медицинские технологии.","vi":"Bệnh viện đang đầu tư vào công nghệ y tế mới.","fa":"این بیمارستان در حال سرمایه گذاری در فناوری جدید پزشکی است."}]},{"word":"der Tee","en":"tea","ru":"чай","vi":"trà","fa":"چای","examples":[{"de":"Ich trinke jeden Morgen eine Tasse Tee.","en":"I drink a cup of tea every morning.","ru":"Я пью чашку чая каждое утро.","vi":"Tôi uống một tách trà mỗi sáng.","fa":"من هر روز صبح یک فنجان چای می نوشم."},{"de":"Möchtest du grünen oder schwarzen Tee?","en":"Would you like green or black tea?","ru":"Хочешь зелёный или чёрный чай?","vi":"Bạn muốn trà xanh hay trà đen?","fa":"چای سبز میخوای یا سیاه؟"}]},{"word":"der Teig","en":"dough","ru":"тесто","vi":"bột","fa":"خمیر","examples":[{"de":"Der Teig muss eine Stunde ruhen.","en":"The dough has to rest for an hour.","ru":"Тесто должно постоять час.","vi":"Bột cần nghỉ trong một giờ.","fa":"خمیر باید یک ساعت استراحت کند."},{"de":"Sie knetet den Teig mit den Händen.","en":"She kneads the dough with her hands.","ru":"Она месит тесто руками.","vi":"Cô ấy nhào bột bằng tay.","fa":"خمیر را با دستانش ورز می دهد."},{"de":"Aus diesem Teig kann man Brötchen backen.","en":"You can bake rolls from this dough.","ru":"Из этого теста можно испечь булочки.","vi":"Bạn có thể nướng cuộn từ bột này.","fa":"می توانید از این خمیر رول بپزید."}]},{"word":"teilen","en":"to share, to divide","ru":"делить(ся)","vi":"chia sẻ","fa":"به اشتراک بگذارید","examples":[{"de":"Wir teilen uns die Kosten für das Geschenk.","en":"We split the cost of the gift.","ru":"Мы делим расходы на подарок.","vi":"Chúng tôi chia sẻ chi phí của món quà.","fa":"ما هزینه هدیه را تقسیم می کنیم."},{"de":"Sie teilt ihr Zimmer mit ihrer Schwester.","en":"She shares her room with her sister.","ru":"Она делит комнату со своей сестрой.","vi":"Cô ở chung phòng với chị gái.","fa":"او اتاقش را با خواهرش تقسیم می کند."}]},{"word":"die Teilnahme","en":"participation; attendance","ru":"участие","vi":"sự tham gia","fa":"مشارکت","examples":[{"de":"Die Teilnahme am Seminar ist kostenlos.","en":"Participation in the seminar is free.","ru":"Участие в семинаре бесплатное.","vi":"Việc tham gia hội thảo là miễn phí.","fa":"شرکت در سمینار رایگان است."},{"de":"Wir freuen uns über deine Teilnahme.","en":"We're glad you're taking part.","ru":"Мы рады твоему участию.","vi":"Chúng tôi mong chờ sự tham gia của bạn.","fa":"منتظر مشارکت شما هستیم"}]},{"word":"teilnehmen","en":"to take part, to participate","ru":"участвовать","vi":"tham gia","fa":"شرکت کنند","examples":[{"de":"Ich möchte an dem Kurs teilnehmen.","en":"I would like to take part in the course.","ru":"Я хотел бы принять участие в курсе.","vi":"Tôi muốn tham gia khóa học.","fa":"من دوست دارم در دوره شرکت کنم."},{"de":"Viele Schüler nehmen an dem Wettbewerb teil.","en":"Many students take part in the competition.","ru":"Многие ученики участвуют в конкурсе.","vi":"Nhiều sinh viên tham gia cuộc thi.","fa":"دانش آموزان زیادی در این مسابقه شرکت می کنند."}]},{"word":"der Teilnehmer","en":"participant (male)","ru":"участник","vi":"người tham gia","fa":"شرکت کننده","examples":[{"de":"Alle Teilnehmer bekommen eine Mappe mit Unterlagen.","en":"All participants receive a folder with documents.","ru":"Все участники получают папку с материалами.","vi":"Tất cả người tham gia đều nhận được một thư mục chứa tài liệu.","fa":"همه شرکت کنندگان یک پوشه با اسناد دریافت می کنند."},{"de":"Der Kurs hat zwanzig Teilnehmer.","en":"The course has twenty participants.","ru":"На курсе двадцать участников.","vi":"Khóa học có hai mươi người tham gia.","fa":"این دوره بیست شرکت کننده دارد."},{"de":"Ein Teilnehmer stellte eine interessante Frage.","en":"A participant asked an interesting question.","ru":"Один участник задал интересный вопрос.","vi":"Một người tham gia đã hỏi một câu hỏi thú vị.","fa":"یکی از شرکت کنندگان سوال جالبی پرسید."}]},{"word":"die Teilnehmerin","en":"participant (female)","ru":"участница","vi":"người tham gia","fa":"شرکت کننده","examples":[{"de":"Jede Teilnehmerin bekommt eine Urkunde.","en":"Every participant gets a certificate.","ru":"Каждая участница получает сертификат.","vi":"Mỗi người tham gia đều nhận được một giấy chứng nhận.","fa":"هر شرکت کننده گواهینامه دریافت می کند."},{"de":"Die Teilnehmerin aus Spanien hat gewonnen.","en":"The participant from Spain won.","ru":"Участница из Испании победила.","vi":"Thí sinh đến từ Tây Ban Nha đã thắng.","fa":"شرکت کننده از اسپانیا برنده شد."}]},{"word":"teilweise","en":"partly, partially","ru":"частично, отчасти","vi":"một phần","fa":"تا حدی","examples":[{"de":"Der Himmel ist heute teilweise bewölkt.","en":"The sky is partly cloudy today.","ru":"Небо сегодня частично облачно.","vi":"Bầu trời hôm nay có mây vài nơi.","fa":"آسمان امروز نیمه ابری است."},{"de":"Die Arbeit ist erst teilweise fertig.","en":"The work is only partly finished.","ru":"Работа выполнена лишь частично.","vi":"Công việc chỉ mới hoàn thành một phần.","fa":"کار فقط تا حدی تمام شده است."},{"de":"Ich stimme dir teilweise zu.","en":"I partly agree with you.","ru":"Я отчасти с тобой согласен.","vi":"Tôi một phần đồng ý với bạn.","fa":"تا حدی با شما موافقم"}]},{"word":"die Teilzeit","en":"part-time work","ru":"неполная занятость, работа на полставки","vi":"bán thời gian","fa":"پاره وقت","examples":[{"de":"Nach der Elternzeit arbeitet sie in Teilzeit.","en":"After parental leave she works part-time.","ru":"После декретного отпуска она работает на полставки.","vi":"Sau khi cha mẹ nghỉ phép, cô ấy làm việc bán thời gian.","fa":"پس از مرخصی والدین، او به صورت نیمه وقت کار می کند."},{"de":"In Teilzeit verdient man natürlich weniger.","en":"Working part-time you naturally earn less.","ru":"При неполной занятости, естественно, зарабатываешь меньше.","vi":"Tất nhiên, bạn kiếm được ít tiền hơn khi làm việc bán thời gian.","fa":"البته، شما درآمد کمتری از کار پاره وقت دارید."},{"de":"Viele Eltern wünschen sich eine Stelle in Teilzeit.","en":"Many parents would like a part-time position.","ru":"Многие родители хотели бы место с неполной занятостью.","vi":"Nhiều bậc cha mẹ muốn có một công việc bán thời gian.","fa":"بسیاری از والدین خواهان شغل پاره وقت هستند."}]},{"word":"die Teilzeitstelle","en":"part-time job","ru":"работа на неполный день, неполная ставка","vi":"vị trí bán thời gian","fa":"موقعیت پاره وقت","examples":[{"de":"Nach der Geburt suchte sie eine Teilzeitstelle.","en":"After the birth she looked for a part-time job.","ru":"После рождения ребёнка она искала работу на неполный день.","vi":"Sau khi sinh con, cô tìm việc làm bán thời gian.","fa":"پس از زایمان، او به دنبال یک کار نیمه وقت بود."},{"de":"Die Firma bietet eine Teilzeitstelle im Büro an.","en":"The company offers a part-time job in the office.","ru":"Компания предлагает работу на неполный день в офисе.","vi":"Công ty tuyển dụng việc làm bán thời gian tại văn phòng.","fa":"این شرکت یک موقعیت پاره وقت در دفتر ارائه می دهد."},{"de":"Eine Teilzeitstelle passt gut zu meinem Studium.","en":"A part-time job fits well with my studies.","ru":"Работа на неполный день хорошо совмещается с учёбой.","vi":"Một công việc bán thời gian phù hợp với việc học của tôi.","fa":"یک شغل پاره وقت به خوبی با تحصیلات من مطابقت دارد."}]},{"word":"telefonieren","en":"to make a phone call, to talk on the phone","ru":"разговаривать по телефону","vi":"gọi điện thoại","fa":"تماس تلفنی برقرار کن","examples":[{"de":"Ich telefoniere gerade mit meiner Mutter.","en":"I am on the phone with my mother right now.","ru":"Я сейчас разговариваю по телефону с мамой.","vi":"Hiện giờ tôi đang nói chuyện điện thoại với mẹ tôi.","fa":"من الان با مادرم تلفنی دارم."},{"de":"Er telefoniert jeden Abend mit seiner Freundin.","en":"He talks on the phone with his girlfriend every evening.","ru":"Он каждый вечер разговаривает по телефону со своей девушкой.","vi":"Anh ấy nói chuyện với bạn gái qua điện thoại mỗi tối.","fa":"او هر روز عصر با دوست دخترش تلفنی صحبت می کند."}]},{"word":"die Telefonliste","en":"telephone list, list of phone numbers","ru":"телефонный список, список телефонных номеров","vi":"danh sách điện thoại","fa":"لیست تلفن","examples":[{"de":"Die Telefonliste hängt neben dem Apparat.","en":"The telephone list hangs next to the phone.","ru":"Телефонный список висит рядом с телефоном.","vi":"Danh sách điện thoại treo cạnh điện thoại.","fa":"لیست تلفن کنار گوشی آویزان است."},{"de":"Bitte tragen Sie Ihre Nummer in die Telefonliste ein.","en":"Please enter your number in the telephone list.","ru":"Пожалуйста, впиши свой номер в телефонный список.","vi":"Vui lòng nhập số điện thoại của bạn vào danh sách điện thoại.","fa":"لطفا شماره خود را در لیست تلفن وارد کنید."},{"de":"Ich finde seinen Namen nicht in der Telefonliste.","en":"I can't find his name in the telephone list.","ru":"Я не могу найти его имя в телефонном списке.","vi":"Tôi không thể tìm thấy tên anh ấy trong danh sách điện thoại.","fa":"من نمی توانم نام او را در لیست تلفن پیدا کنم."}]},{"word":"das Teleskop","en":"telescope","ru":"телескоп","vi":"kính thiên văn","fa":"تلسکوپ","examples":[{"de":"Durch das Teleskop konnten wir die Ringe des Saturn erkennen.","en":"Through the telescope we could make out the rings of Saturn.","ru":"В телескоп мы смогли разглядеть кольца Сатурна.","vi":"Qua kính viễn vọng, chúng tôi có thể nhìn thấy các vành đai của Sao Thổ.","fa":"از طریق تلسکوپ توانستیم حلقه های زحل را ببینیم."},{"de":"Mit einem guten Teleskop kann man die Mondkrater sehen.","en":"With a good telescope you can see the craters of the moon.","ru":"В хороший телескоп можно увидеть лунные кратеры.","vi":"Với một kính thiên văn tốt, bạn có thể nhìn thấy các miệng hố trên mặt trăng.","fa":"با یک تلسکوپ خوب می توانید دهانه های ماه را ببینید."},{"de":"Das neue Teleskop liefert beeindruckende Bilder ferner Sterne.","en":"The new telescope delivers impressive images of distant stars.","ru":"Новый телескоп даёт впечатляющие изображения далёких звёзд.","vi":"Kính thiên văn mới mang lại những hình ảnh ấn tượng về các ngôi sao ở xa.","fa":"تلسکوپ جدید تصاویر قابل توجهی از ستاره های دور ارائه می دهد."}]},{"word":"der Teller","en":"plate","ru":"тарелка","vi":"cái đĩa","fa":"بشقاب","examples":[{"de":"Stell die Teller bitte auf den Tisch.","en":"Please put the plates on the table.","ru":"Поставь, пожалуйста, тарелки на стол.","vi":"Vui lòng đặt những chiếc đĩa lên bàn.","fa":"لطفا بشقاب ها را روی میز بگذارید."},{"de":"Mein Teller ist schon leer.","en":"My plate is already empty.","ru":"Моя тарелка уже пуста.","vi":"Đĩa của tôi đã trống rồi.","fa":"بشقاب من در حال حاضر خالی است."}]},{"word":"die Temperatur","en":"temperature","ru":"температура","vi":"nhiệt độ","fa":"دما","examples":[{"de":"Die Temperatur steigt heute auf 30 Grad.","en":"The temperature rises to 30 degrees today.","ru":"Сегодня температура поднимется до 30 градусов.","vi":"Nhiệt độ hôm nay sẽ tăng lên 30 độ.","fa":"دمای هوا امروز به 30 درجه می رسد."},{"de":"Der Arzt misst die Temperatur des Patienten.","en":"The doctor measures the patient's temperature.","ru":"Врач измеряет температуру пациента.","vi":"Bác sĩ đo nhiệt độ cho bệnh nhân.","fa":"پزشک دمای بدن بیمار را اندازه گیری می کند."}]},{"word":"der Temperaturanstieg","en":"temperature rise","ru":"повышение температуры, рост температуры","vi":"der Nhiệt độ","fa":"افزایش دما","examples":[{"de":"Der Temperaturanstieg bedroht viele Tierarten.","en":"The temperature rise threatens many animal species.","ru":"Повышение температуры угрожает многим видам животных.","vi":"Nhiệt độ tăng cao đe dọa nhiều loài động vật.","fa":"افزایش دما بسیاری از گونه های جانوری را تهدید می کند."},{"de":"Wissenschaftler warnen vor einem schnellen Temperaturanstieg.","en":"Scientists warn of a rapid temperature rise.","ru":"Учёные предупреждают о быстром повышении температуры.","vi":"Các nhà khoa học cảnh báo về sự gia tăng nhanh chóng của nhiệt độ.","fa":"دانشمندان نسبت به افزایش سریع دما هشدار می دهند."},{"de":"Der Temperaturanstieg lässt die Gletscher schmelzen.","en":"The temperature rise is causing the glaciers to melt.","ru":"Повышение температуры заставляет ледники таять.","vi":"Nhiệt độ tăng cao khiến các sông băng tan chảy.","fa":"افزایش دما باعث ذوب شدن یخچال ها می شود."}]},{"word":"das Tempo","en":"speed, pace","ru":"темп, скорость","vi":"tốc độ","fa":"سرعت","examples":[{"de":"Bitte reduzieren Sie das Tempo in der Stadt.","en":"Please reduce your speed in the city.","ru":"Пожалуйста, снизьте скорость в городе.","vi":"Hãy giảm tốc độ trong thành phố.","fa":"لطفا سرعت خود را در شهر کم کنید."},{"de":"Das Tempo des Films war zu langsam.","en":"The pace of the movie was too slow.","ru":"Темп фильма был слишком медленным.","vi":"Nhịp phim quá chậm.","fa":"سرعت فیلم خیلی کند بود."}]},{"word":"das Tempolimit","en":"speed limit","ru":"ограничение скорости","vi":"giới hạn tốc độ","fa":"محدودیت سرعت","examples":[{"de":"Auf dieser Straße gilt ein Tempolimit von fünfzig.","en":"On this road there is a speed limit of fifty.","ru":"На этой дороге ограничение скорости пятьдесят.","vi":"Có giới hạn tốc độ là năm mươi trên con đường này.","fa":"در این جاده محدودیت سرعت پنجاه وجود دارد."},{"de":"Viele Leute halten das Tempolimit nicht ein.","en":"Many people do not stick to the speed limit.","ru":"Многие не соблюдают ограничение скорости.","vi":"Nhiều người không tuân theo giới hạn tốc độ.","fa":"بسیاری از افراد محدودیت سرعت را رعایت نمی کنند."},{"de":"In Deutschland gibt es auf manchen Autobahnen kein Tempolimit.","en":"In Germany there is no speed limit on some motorways.","ru":"В Германии на некоторых автострадах нет ограничения скорости.","vi":"Ở Đức không có giới hạn tốc độ trên một số đường cao tốc.","fa":"در آلمان محدودیت سرعت در برخی از بزرگراه ها وجود ندارد."}]},{"word":"die Tendenz","en":"tendency, trend","ru":"тенденция","vi":"xu hướng","fa":"گرایش","examples":[{"de":"Die Zahlen zeigen eine steigende Tendenz.","en":"The figures show a rising tendency.","ru":"Цифры показывают растущую тенденцию.","vi":"Những con số cho thấy một xu hướng ngày càng tăng.","fa":"اعداد نشان دهنده روند افزایشی است."},{"de":"Es gibt eine klare Tendenz zu mehr Online-Käufen.","en":"There is a clear trend towards more online purchases.","ru":"Есть чёткая тенденция к росту онлайн-покупок.","vi":"Có một xu hướng rõ ràng là mua hàng trực tuyến nhiều hơn.","fa":"روند واضحی به سمت خریدهای آنلاین بیشتر وجود دارد."},{"de":"Die Tendenz lässt sich aus den Daten ablesen.","en":"The trend can be read off from the data.","ru":"Тенденцию можно считать по данным.","vi":"Xu hướng có thể được nhìn thấy từ dữ liệu.","fa":"روند را می توان از داده ها مشاهده کرد."}]},{"word":"das Tennis","en":"tennis","ru":"теннис","vi":"quần vợt","fa":"تنیس","examples":[{"de":"Am Wochenende spielen wir Tennis.","en":"On the weekend we play tennis.","ru":"На выходных мы играем в теннис.","vi":"Vào cuối tuần chúng tôi chơi quần vợt.","fa":"آخر هفته تنیس بازی می کنیم."},{"de":"Sie trainiert dreimal pro Woche Tennis.","en":"She trains tennis three times a week.","ru":"Она тренируется по теннису три раза в неделю.","vi":"Cô ấy tập tennis ba lần một tuần.","fa":"او هفته ای سه بار تنیس تمرین می کند."}]},{"word":"der Teppich","en":"carpet, rug","ru":"ковёр","vi":"tấm thảm","fa":"فرش","examples":[{"de":"Der Teppich im Wohnzimmer ist sehr weich.","en":"The carpet in the living room is very soft.","ru":"Ковёр в гостиной очень мягкий.","vi":"Thảm trong phòng khách rất mềm.","fa":"فرش اتاق نشیمن بسیار نرم است."},{"de":"Wir haben einen neuen Teppich gekauft.","en":"We bought a new carpet.","ru":"Мы купили новый ковёр.","vi":"Chúng tôi đã mua một tấm thảm mới.","fa":"فرش نو خریدیم."}]},{"word":"der Termin","en":"appointment","ru":"назначенная встреча, приём","vi":"cuộc hẹn","fa":"قرار ملاقات","examples":[{"de":"Ich habe morgen einen Termin beim Zahnarzt.","en":"I have an appointment at the dentist's tomorrow.","ru":"У меня завтра приём у стоматолога.","vi":"Tôi có cuộc hẹn với nha sĩ vào ngày mai.","fa":"فردا وقت دندانپزشکی دارم."},{"de":"Können wir einen anderen Termin vereinbaren?","en":"Can we arrange another appointment?","ru":"Можем ли мы назначить другую встречу?","vi":"Chúng ta có thể sắp xếp một cuộc hẹn khác được không?","fa":"آیا می توانیم تاریخ دیگری را ترتیب دهیم؟"}]},{"word":"der Terminkalender","en":"appointment calendar, diary","ru":"ежедневник, органайзер встреч","vi":"lịch hẹn","fa":"تقویم قرار ملاقات","examples":[{"de":"Ich trage den Arzttermin gleich in meinen Terminkalender ein.","en":"I'll enter the doctor's appointment in my diary straight away.","ru":"Я сразу запишу приём у врача в ежедневник.","vi":"Tôi sẽ ghi ngay cuộc hẹn với bác sĩ vào lịch hẹn của mình.","fa":"فوراً نوبت دکتر را در تقویم قرار ملاقاتم می گذارم."},{"de":"Mein Terminkalender ist diese Woche völlig voll.","en":"My diary is completely full this week.","ru":"Мой ежедневник на этой неделе полностью забит.","vi":"Lịch trình của tôi tuần này đã kín hoàn toàn.","fa":"برنامه من این هفته کاملا پر است."},{"de":"Schau bitte in deinen Terminkalender, ob du Zeit hast.","en":"Please look in your diary to see if you have time.","ru":"Посмотри в ежедневник, есть ли у тебя время.","vi":"Vui lòng kiểm tra lịch hẹn của bạn để xem bạn có thời gian không.","fa":"لطفاً تقویم قرار ملاقات خود را بررسی کنید تا ببینید آیا وقت دارید یا خیر."}]},{"word":"die Terrasse","en":"terrace, patio","ru":"терраса","vi":"sân thượng","fa":"تراس","examples":[{"de":"Im Sommer essen wir oft auf der Terrasse.","en":"In summer we often eat on the terrace.","ru":"Летом мы часто едим на террасе.","vi":"Vào mùa hè chúng tôi thường ăn trên sân thượng.","fa":"در تابستان اغلب در تراس غذا می خوریم."},{"de":"Die Wohnung hat eine große Terrasse.","en":"The apartment has a large terrace.","ru":"В квартире большая терраса.","vi":"Căn hộ có sân hiên rộng.","fa":"آپارتمان دارای تراس بزرگ است."}]},{"word":"testen","en":"to test","ru":"тестировать, испытывать","vi":"kiểm tra","fa":"تست کنید","examples":[{"de":"Der Techniker testet das neue Gerät.","en":"The technician tests the new device.","ru":"Техник тестирует новое устройство.","vi":"Kỹ thuật viên kiểm tra thiết bị mới.","fa":"تکنسین دستگاه جدید را آزمایش می کند."},{"de":"Wir haben das Auto vor dem Kauf getestet.","en":"We tested the car before buying it.","ru":"Мы протестировали машину перед покупкой.","vi":"Chúng tôi đã kiểm tra chiếc xe trước khi mua nó.","fa":"ما قبل از خرید ماشین را تست کردیم."}]},{"word":"teuer","en":"expensive","ru":"дорогой","vi":"đắt tiền","fa":"گران قیمت","examples":[{"de":"Dieses Restaurant ist mir zu teuer.","en":"This restaurant is too expensive for me.","ru":"Этот ресторан для меня слишком дорогой.","vi":"Nhà hàng này quá đắt đối với tôi.","fa":"این رستوران برای من خیلی گران است."},{"de":"Die Mieten in der Stadt sind sehr teuer geworden.","en":"Rents in the city have become very expensive.","ru":"Аренда в городе стала очень дорогой.","vi":"Giá thuê nhà trong thành phố đã trở nên rất đắt đỏ.","fa":"اجاره در شهر بسیار گران شده است."}]},{"word":"der Text","en":"text","ru":"текст","vi":"văn bản","fa":"متن","examples":[{"de":"Bitte lesen Sie den Text genau durch.","en":"Please read the text carefully.","ru":"Пожалуйста, внимательно прочитайте текст.","vi":"Xin vui lòng đọc văn bản một cách cẩn thận.","fa":"لطفا متن را با دقت بخوانید."},{"de":"Der Text ist sehr lang.","en":"The text is very long.","ru":"Текст очень длинный.","vi":"Văn bản rất dài.","fa":"متن بسیار طولانی است."}]},{"word":"das Theater","en":"theater","ru":"театр","vi":"nhà hát","fa":"تئاتر","examples":[{"de":"Wir gehen heute Abend ins Theater.","en":"We are going to the theater tonight.","ru":"Мы идём сегодня вечером в театр.","vi":"Tối nay chúng ta sẽ đến rạp hát.","fa":"امشب میریم تئاتر"},{"de":"Das Stück im Theater war sehr spannend.","en":"The play at the theater was very exciting.","ru":"Спектакль в театре был очень захватывающим.","vi":"Vở kịch trong rạp rất thú vị.","fa":"بازی در تئاتر بسیار هیجان انگیز بود."}]},{"word":"das Thema","en":"topic, theme","ru":"тема","vi":"chủ đề","fa":"موضوع","examples":[{"de":"Das Thema der Diskussion ist Klimaschutz.","en":"The topic of the discussion is climate protection.","ru":"Тема дискуссии — защита климата.","vi":"Chủ đề của cuộc thảo luận là bảo vệ khí hậu.","fa":"موضوع بحث حفاظت از اقلیم است."},{"de":"Wir haben in der Schule über ein interessantes Thema gesprochen.","en":"We talked about an interesting topic at school.","ru":"Мы говорили об интересной теме в школе.","vi":"Chúng tôi đã nói về một chủ đề thú vị ở trường.","fa":"در مدرسه درباره موضوع جالبی صحبت کردیم."}]},{"word":"theoretisch","en":"theoretical","ru":"теоретический","vi":"về mặt lý thuyết","fa":"به صورت تئوری","examples":[{"de":"Theoretisch könnte das funktionieren.","en":"Theoretically, that could work.","ru":"Теоретически это могло бы сработать.","vi":"Về lý thuyết điều này có thể hoạt động.","fa":"در تئوری این می تواند کار کند."},{"de":"Wir haben viel theoretisches Wissen, aber wenig Praxis.","en":"We have a lot of theoretical knowledge but little practice.","ru":"У нас много теоретических знаний, но мало практики.","vi":"Chúng ta có rất nhiều kiến ​​thức lý thuyết nhưng lại có rất ít thực hành.","fa":"ما دانش نظری زیادی داریم، اما عمل کمی داریم."}]},{"word":"die Theorie","en":"theory","ru":"теория","vi":"lý thuyết","fa":"نظریه","examples":[{"de":"In der Theorie klingt der Plan gut.","en":"In theory the plan sounds good.","ru":"В теории план звучит хорошо.","vi":"Về lý thuyết thì kế hoạch này nghe có vẻ ổn.","fa":"در تئوری این طرح خوب به نظر می رسد."},{"de":"Er kennt die Theorie, aber nicht die Praxis.","en":"He knows the theory but not the practice.","ru":"Он знает теорию, но не практику.","vi":"Anh ta biết lý thuyết nhưng không biết thực hành.","fa":"او تئوری را می داند، اما عمل را نه."},{"de":"Diese Theorie konnte bisher niemand beweisen.","en":"Nobody has been able to prove this theory so far.","ru":"Эту теорию пока никто не смог доказать.","vi":"Chưa có ai có thể chứng minh lý thuyết này.","fa":"هنوز کسی نتوانسته این نظریه را اثبات کند."}]},{"word":"die Therapeutin","en":"therapist (female)","ru":"терапевт (женщина); психотерапевт","vi":"nhà trị liệu","fa":"درمانگر","examples":[{"de":"Die Therapeutin berät junge Familien.","en":"The therapist advises young families.","ru":"Терапевт консультирует молодые семьи.","vi":"Nhà trị liệu tư vấn cho các gia đình trẻ.","fa":"درمانگر به خانواده های جوان توصیه می کند."},{"de":"Die Therapeutin hört ihren Patienten geduldig zu.","en":"The therapist listens patiently to her patients.","ru":"Терапевт терпеливо выслушивает своих пациентов.","vi":"Nhà trị liệu kiên nhẫn lắng nghe bệnh nhân của mình.","fa":"درمانگر با حوصله به بیماران خود گوش می دهد."},{"de":"Nach dem Unfall ging er regelmäßig zu einer Therapeutin.","en":"After the accident he went to a therapist regularly.","ru":"После аварии он регулярно ходил к терапевту.","vi":"Sau vụ tai nạn, anh thường xuyên đến gặp bác sĩ trị liệu.","fa":"پس از تصادف، او مرتب به یک درمانگر مراجعه می کرد."}]},{"word":"die Therapie","en":"therapy","ru":"терапия","vi":"liệu pháp","fa":"درمان","examples":[{"de":"Nach dem Unfall begann seine Therapie.","en":"His therapy began after the accident.","ru":"После аварии началась его терапия.","vi":"Sau vụ tai nạn, quá trình trị liệu của anh bắt đầu.","fa":"پس از تصادف، درمان او شروع شد."},{"de":"Sie macht eine Therapie gegen ihre Angst.","en":"She is undergoing therapy for her anxiety.","ru":"Она проходит терапию от своего страха.","vi":"Cô ấy đang được điều trị chứng lo âu của mình.","fa":"او تحت درمان برای اضطراب خود است."}]},{"word":"das Thermometer","en":"thermometer","ru":"термометр; градусник","vi":"nhiệt kế","fa":"دماسنج","examples":[{"de":"Das Thermometer zeigt heute minus fünf Grad an.","en":"The thermometer reads minus five degrees today.","ru":"Термометр показывает сегодня минус пять градусов.","vi":"Nhiệt kế hôm nay chỉ âm 5 độ.","fa":"دماسنج امروز منفی پنج درجه را نشان می دهد."},{"de":"Die Krankenschwester steckte dem Kind ein Thermometer unter die Zunge.","en":"The nurse put a thermometer under the child's tongue.","ru":"Медсестра положила ребёнку градусник под язык.","vi":"Y tá nhét nhiệt kế vào dưới lưỡi đứa trẻ.","fa":"پرستار دماسنج را زیر زبان کودک گذاشت."},{"de":"Mit dem digitalen Thermometer misst man das Fieber in wenigen Sekunden.","en":"With the digital thermometer you can measure a fever in just a few seconds.","ru":"Цифровым термометром температуру измеряют за несколько секунд.","vi":"Với nhiệt kế kỹ thuật số, bạn có thể đo cơn sốt của mình chỉ trong vài giây.","fa":"با دماسنج دیجیتال می توانید تب خود را تنها در چند ثانیه اندازه گیری کنید."}]},{"word":"das Ticket","en":"ticket","ru":"билет","vi":"vé","fa":"بلیط","examples":[{"de":"Ich habe ein Ticket für den Zug gekauft.","en":"I bought a ticket for the train.","ru":"Я купил билет на поезд.","vi":"Tôi đã mua vé tàu.","fa":"بلیت قطار خریدم."},{"de":"Die Tickets für das Konzert sind schon ausverkauft.","en":"The tickets for the concert are already sold out.","ru":"Билеты на концерт уже распроданы.","vi":"Vé cho buổi hòa nhạc đã được bán hết.","fa":"بلیت های کنسرت از قبل فروخته شده است."}]},{"word":"tief","en":"deep","ru":"глубокий","vi":"sâu","fa":"عمیق","examples":[{"de":"Der See ist an dieser Stelle sehr tief.","en":"The lake is very deep at this spot.","ru":"Озеро в этом месте очень глубокое.","vi":"Hồ lúc này rất sâu.","fa":"دریاچه در این نقطه بسیار عمیق است."},{"de":"Er atmete tief durch.","en":"He took a deep breath.","ru":"Он глубоко вдохнул.","vi":"Anh hít một hơi thật sâu.","fa":"نفس عمیقی کشید."}]},{"word":"die Tiefatmung","en":"deep breathing","ru":"глубокое дыхание","vi":"hơi thở sâu","fa":"نفس عمیق","examples":[{"de":"Tiefatmung hilft beim Entspannen.","en":"Deep breathing helps with relaxing.","ru":"Глубокое дыхание помогает расслабиться.","vi":"Hít thở sâu giúp bạn thư giãn.","fa":"تنفس عمیق به آرامش شما کمک می کند."},{"de":"Vor der Meditation üben wir die Tiefatmung.","en":"Before the meditation we practise deep breathing.","ru":"Перед медитацией мы практикуем глубокое дыхание.","vi":"Trước khi thiền chúng ta tập thở sâu.","fa":"قبل از مدیتیشن، تنفس عمیق را تمرین می کنیم."},{"de":"Durch Tiefatmung kann man Stress abbauen.","en":"Through deep breathing you can reduce stress.","ru":"С помощью глубокого дыхания можно снять стресс.","vi":"Bạn có thể giảm căng thẳng bằng cách hít thở sâu.","fa":"با تنفس عمیق می توانید استرس را کاهش دهید."}]},{"word":"die Tiefkühlkost","en":"frozen food","ru":"замороженные продукты","vi":"thực phẩm đông lạnh","fa":"غذای منجمد","examples":[{"de":"Tiefkühlkost ist praktisch, aber nicht immer gesund.","en":"Frozen food is practical but not always healthy.","ru":"Замороженные продукты удобны, но не всегда полезны.","vi":"Thực phẩm đông lạnh là thực tế nhưng không phải lúc nào cũng tốt cho sức khỏe.","fa":"غذای منجمد عملی است، اما همیشه سالم نیست."},{"de":"Im Supermarkt gibt es eine große Auswahl an Tiefkühlkost.","en":"There is a large selection of frozen food in the supermarket.","ru":"В супермаркете большой выбор замороженных продуктов.","vi":"Có rất nhiều lựa chọn thực phẩm đông lạnh trong siêu thị.","fa":"انتخاب زیادی از غذاهای منجمد در سوپرمارکت وجود دارد."},{"de":"Ich koche lieber frisch als mit Tiefkühlkost.","en":"I prefer to cook fresh rather than with frozen food.","ru":"Я предпочитаю готовить из свежего, а не из замороженного.","vi":"Tôi thích nấu đồ tươi hơn là đồ đông lạnh.","fa":"من ترجیح می دهم غذاهای تازه بپزم تا منجمد."}]},{"word":"das Tier","en":"animal","ru":"животное","vi":"con vật","fa":"حیوان","examples":[{"de":"Der Hund ist mein Lieblingstier.","en":"The dog is my favorite animal.","ru":"Собака — моё любимое животное.","vi":"Con chó là động vật yêu thích của tôi.","fa":"سگ حیوان مورد علاقه من است."},{"de":"Im Zoo kann man viele Tiere sehen.","en":"You can see many animals in the zoo.","ru":"В зоопарке можно увидеть много животных.","vi":"Bạn có thể nhìn thấy nhiều loài động vật trong sở thú.","fa":"شما می توانید حیوانات زیادی را در باغ وحش ببینید."}]},{"word":"das Tierheim","en":"animal shelter","ru":"приют для животных","vi":"nơi trú ẩn động vật","fa":"پناهگاه حیوانات","examples":[{"de":"Wir haben unseren Hund aus dem Tierheim geholt.","en":"We got our dog from the animal shelter.","ru":"Мы взяли нашу собаку из приюта для животных.","vi":"Chúng tôi nhận được con chó của mình từ nơi trú ẩn động vật.","fa":"سگمان را از پناهگاه حیوانات گرفتیم."},{"de":"Im Tierheim warten viele Katzen auf ein neues Zuhause.","en":"In the animal shelter many cats are waiting for a new home.","ru":"В приюте для животных многие кошки ждут нового дома.","vi":"Có rất nhiều chú mèo ở nơi trú ẩn động vật đang chờ đợi một ngôi nhà mới.","fa":"گربه های زیادی در پناهگاه حیوانات منتظر خانه جدید هستند."},{"de":"Sie arbeitet ehrenamtlich im Tierheim.","en":"She works as a volunteer at the animal shelter.","ru":"Она работает волонтёром в приюте для животных.","vi":"Cô tình nguyện tại nơi trú ẩn động vật.","fa":"او در پناهگاه حیوانات داوطلب می شود."}]},{"word":"der Tierpark","en":"animal park, zoo","ru":"зоопарк","vi":"sở thú","fa":"باغ وحش","examples":[{"de":"Am Sonntag gehen wir mit den Kindern in den Tierpark.","en":"On Sunday we are going to the animal park with the children.","ru":"В воскресенье мы идём с детьми в зоопарк.","vi":"Vào Chủ nhật chúng tôi đi sở thú với bọn trẻ.","fa":"یکشنبه با بچه ها به باغ وحش می رویم."},{"de":"Im Tierpark gibt es Löwen, Affen und Elefanten.","en":"In the animal park there are lions, monkeys and elephants.","ru":"В зоопарке есть львы, обезьяны и слоны.","vi":"Có sư tử, khỉ và voi trong sở thú.","fa":"در باغ وحش شیر، میمون و فیل وجود دارد."},{"de":"Der Tierpark ist im Sommer länger geöffnet.","en":"The animal park is open longer in summer.","ru":"Летом зоопарк открыт дольше.","vi":"Vườn thú mở cửa lâu hơn vào mùa hè.","fa":"باغ وحش در تابستان بیشتر باز است."}]},{"word":"der Tipp","en":"tip, hint","ru":"совет, подсказка","vi":"tiền boa","fa":"نوک","examples":[{"de":"Kannst du mir einen Tipp geben?","en":"Can you give me a tip?","ru":"Можешь дать мне совет?","vi":"Bạn có thể cho tôi một lời khuyên?","fa":"میشه راهنماییم کنید"},{"de":"Danke für den guten Tipp.","en":"Thanks for the good tip.","ru":"Спасибо за хороший совет.","vi":"Cảm ơn vì lời khuyên tốt.","fa":"ممنون از راهنمایی خوب"}]},{"word":"tippen","en":"to type","ru":"печатать (на клавиатуре)","vi":"gõ nhẹ","fa":"تایپ کردن","examples":[{"de":"Sie tippt sehr schnell auf dem Computer.","en":"She types very fast on the computer.","ru":"Она очень быстро печатает на компьютере.","vi":"Cô ấy gõ rất nhanh trên máy tính.","fa":"او خیلی سریع روی کامپیوتر تایپ می کند."},{"de":"Ich muss noch eine E-Mail tippen.","en":"I still need to type an email.","ru":"Мне ещё нужно напечатать письмо.","vi":"Tôi vẫn phải gõ email.","fa":"من هنوز باید یک ایمیل تایپ کنم."}]},{"word":"der Tisch","en":"table","ru":"стол","vi":"cái bàn","fa":"جدول","examples":[{"de":"Das Essen steht auf dem Tisch.","en":"The food is on the table.","ru":"Еда стоит на столе.","vi":"Thức ăn ở trên bàn.","fa":"غذا روی میز است."},{"de":"Wir haben einen neuen Tisch für die Küche gekauft.","en":"We bought a new table for the kitchen.","ru":"Мы купили новый стол для кухни.","vi":"Chúng tôi đã mua một chiếc bàn mới cho nhà bếp.","fa":"یک میز جدید برای آشپزخانه خریدیم."}]},{"word":"der Titel","en":"title","ru":"название, заголовок","vi":"tiêu đề","fa":"عنوان","examples":[{"de":"Wie lautet der Titel des Buches?","en":"What is the title of the book?","ru":"Как называется книга?","vi":"Tiêu đề của cuốn sách là gì?","fa":"عنوان کتاب چیست؟"},{"de":"Der Film hat einen interessanten Titel.","en":"The movie has an interesting title.","ru":"У фильма интересное название.","vi":"Phim có tựa đề khá thú vị.","fa":"این فیلم عنوان جالبی دارد."}]},{"word":"die Tochter","en":"daughter","ru":"дочь","vi":"con gái","fa":"دختر","examples":[{"de":"Meine Tochter geht in die dritte Klasse.","en":"My daughter is in third grade.","ru":"Моя дочь учится в третьем классе.","vi":"Con gái tôi đang học lớp ba.","fa":"دختر من کلاس سوم است."},{"de":"Sie hat zwei Töchter und einen Sohn.","en":"She has two daughters and a son.","ru":"У неё две дочери и один сын.","vi":"Cô có hai con gái và một con trai.","fa":"او دو دختر و یک پسر دارد."}]},{"word":"der Tod","en":"death","ru":"смерть","vi":"cái chết","fa":"مرگ","examples":[{"de":"Der Tod ihres Vaters war ein großer Schock.","en":"Her father's death was a big shock.","ru":"Смерть её отца стала большим шоком.","vi":"Cái chết của cha cô là một cú sốc lớn.","fa":"مرگ پدرش شوک بزرگی بود."},{"de":"Nach seinem Tod übernahm sein Sohn die Firma.","en":"After his death, his son took over the company.","ru":"После его смерти сын принял на себя управление фирмой.","vi":"Sau khi ông qua đời, con trai ông tiếp quản công ty.","fa":"پس از مرگ او، پسرش مسئولیت شرکت را بر عهده گرفت."}]},{"word":"tödlich","en":"fatal, deadly, lethal","ru":"смертельный, летальный","vi":"gây tử vong","fa":"کشنده","examples":[{"de":"Der Unfall hatte tödliche Folgen.","en":"The accident had fatal consequences.","ru":"Авария имела смертельные последствия.","vi":"Vụ tai nạn đã để lại hậu quả chết người.","fa":"این تصادف عواقب مرگباری داشت."},{"de":"Diese Pflanze ist für Tiere tödlich.","en":"This plant is deadly for animals.","ru":"Это растение смертельно для животных.","vi":"Loại cây này gây tử vong cho động vật.","fa":"این گیاه برای حیوانات کشنده است."},{"de":"Bei dem Brand kam ein Mann tödlich ums Leben.","en":"A man was fatally killed in the fire.","ru":"При пожаре смертельно погиб один мужчина.","vi":"Một người đàn ông thiệt mạng trong vụ cháy.","fa":"یک مرد در آتش سوزی کشته شد."}]},{"word":"die Toilette","en":"toilet, restroom","ru":"туалет","vi":"nhà vệ sinh","fa":"توالت","examples":[{"de":"Wo ist hier bitte die Toilette?","en":"Where is the restroom here, please?","ru":"Где здесь туалет, пожалуйста?","vi":"Xin hỏi nhà vệ sinh ở đây ở đâu?","fa":"توالت اینجا کجاست لطفا؟"},{"de":"Die Toilette im Zug war sauber.","en":"The toilet on the train was clean.","ru":"Туалет в поезде был чистым.","vi":"Nhà vệ sinh trên tàu sạch sẽ.","fa":"توالت داخل قطار تمیز بود."}]},{"word":"tolerant","en":"tolerant","ru":"терпимый, толерантный","vi":"khoan dung","fa":"متحمل","examples":[{"de":"Meine Eltern sind sehr tolerant gegenüber anderen Meinungen.","en":"My parents are very tolerant of other opinions.","ru":"Мои родители очень терпимы к другим мнениям.","vi":"Cha mẹ tôi rất khoan dung với những ý kiến khác.","fa":"پدر و مادرم نسبت به نظرات دیگر بسیار تحمل می کنند."},{"de":"Man sollte gegenüber fremden Kulturen tolerant sein.","en":"One should be tolerant towards foreign cultures.","ru":"Нужно быть терпимым к чужим культурам.","vi":"Người ta phải khoan dung với các nền văn hóa nước ngoài.","fa":"باید با فرهنگ های بیگانه مدارا کرد."}]},{"word":"die Toleranz","en":"tolerance","ru":"терпимость, толерантность","vi":"sự khoan dung","fa":"تحمل","examples":[{"de":"Toleranz ist die Grundlage für ein friedliches Zusammenleben.","en":"Tolerance is the basis for peaceful coexistence.","ru":"Терпимость — основа мирного сосуществования.","vi":"Khoan dung là nền tảng cho sự chung sống hòa bình.","fa":"مدارا اساس همزیستی مسالمت آمیز است."},{"de":"In einer vielfältigen Gesellschaft braucht man viel Toleranz.","en":"In a diverse society one needs a great deal of tolerance.","ru":"В многообразном обществе нужно много терпимости.","vi":"Trong một xã hội đa dạng, bạn cần rất nhiều sự khoan dung.","fa":"در یک جامعه متنوع شما نیاز به تحمل زیادی دارید."},{"de":"Sie zeigte Toleranz gegenüber anderen Meinungen.","en":"She showed tolerance towards other opinions.","ru":"Она проявила терпимость к другим мнениям.","vi":"Cô ấy tỏ ra khoan dung với những ý kiến ​​​​khác.","fa":"او نسبت به نظرات دیگر مدارا کرد."}]},{"word":"toll","en":"great, awesome","ru":"классный, потрясающий","vi":"tuyệt vời","fa":"عالی","examples":[{"de":"Das Konzert war wirklich toll!","en":"The concert was really great!","ru":"Концерт был действительно классным!","vi":"Buổi hòa nhạc thực sự tuyệt vời!","fa":"کنسرت واقعا عالی بود!"},{"de":"Wir hatten einen tollen Urlaub.","en":"We had a great vacation.","ru":"У нас был потрясающий отпуск.","vi":"Chúng tôi đã có một kỳ nghỉ tuyệt vời.","fa":"تعطیلات عالی داشتیم"}]},{"word":"die Tomate","en":"tomato","ru":"помидор","vi":"cà chua","fa":"گوجه فرنگی","examples":[{"de":"Ich schneide die Tomaten für den Salat.","en":"I am cutting the tomatoes for the salad.","ru":"Я нарезаю помидоры для салата.","vi":"Tôi cắt cà chua cho món salad.","fa":"برای سالاد گوجه فرنگی را برش دادم."},{"de":"Die Tomaten aus dem Garten schmecken besonders gut.","en":"The tomatoes from the garden taste especially good.","ru":"Помидоры из огорода особенно вкусные.","vi":"Cà chua từ vườn có hương vị đặc biệt ngon.","fa":"گوجه‌فرنگی‌های باغ به‌ویژه طعم خوبی دارند."}]},{"word":"Tomaten auf den Augen haben","en":"to fail to see the obvious","ru":"не видеть очевидного (как без глаз)","vi":"không nhìn thấy điều hiển nhiên","fa":"ناتوانی در دیدن چیزهای بدیهی","examples":[{"de":"Der Käse stand direkt vor dir — du hast wohl Tomaten auf den Augen!","en":"The cheese was right in front of you — are you blind?!","ru":"Сыр стоял прямо перед тобой — ты будто слепой!","vi":"Phô mai ở ngay trước mặt bạn - bạn phải có cà chua trong mắt!","fa":"پنیر درست جلوی شما بود - حتماً در چشمانتان گوجه فرنگی دارید!"}]},{"word":"der Topf","en":"pot","ru":"кастрюля","vi":"cái nồi","fa":"گلدان","examples":[{"de":"Der Topf mit der Suppe steht auf dem Herd.","en":"The pot with the soup is on the stove.","ru":"Кастрюля с супом стоит на плите.","vi":"Nồi súp đang ở trên bếp.","fa":"قابلمه سوپ روی اجاق است."},{"de":"Sie kocht die Kartoffeln in einem großen Topf.","en":"She cooks the potatoes in a large pot.","ru":"Она варит картошку в большой кастрюле.","vi":"Cô ấy nấu khoai tây trong một cái nồi lớn.","fa":"او سیب زمینی ها را در یک قابلمه بزرگ می پزد."}]},{"word":"das Tor","en":"gate; goal (sports)","ru":"ворота","vi":"cánh cổng","fa":"دروازه","examples":[{"de":"Das Tor zum Garten war offen.","en":"The gate to the garden was open.","ru":"Ворота в сад были открыты.","vi":"Cánh cổng vào vườn đã mở.","fa":"دروازه باغ باز بود."},{"de":"Er hat in der letzten Minute das entscheidende Tor geschossen.","en":"He scored the decisive goal in the last minute.","ru":"Он забил решающий гол в последнюю минуту.","vi":"Anh ghi bàn thắng quyết định ở phút cuối cùng.","fa":"او در آخرین دقیقه گل تعیین کننده را به ثمر رساند."}]},{"word":"die Torte","en":"cake, gateau","ru":"торт","vi":"cái bánh","fa":"کیک","examples":[{"de":"Zum Geburtstag hat sie eine Torte gebacken.","en":"She baked a cake for the birthday.","ru":"На день рождения она испекла торт.","vi":"Cô ấy đã nướng một chiếc bánh cho ngày sinh nhật của mình.","fa":"برای تولدش کیک پخت."},{"de":"Die Torte mit Schokolade war köstlich.","en":"The chocolate cake was delicious.","ru":"Шоколадный торт был восхитительным.","vi":"Bánh sô cô la rất ngon.","fa":"کیک شکلاتی خوشمزه بود."}]},{"word":"der Torwart","en":"goalkeeper","ru":"вратарь","vi":"thủ môn","fa":"دروازه بان","examples":[{"de":"Der Torwart hat den Ball gehalten.","en":"The goalkeeper saved the ball.","ru":"Вратарь отбил мяч.","vi":"Thủ môn đã cứu được bóng.","fa":"دروازه بان توپ را نجات داد."},{"de":"Unser Torwart ist der beste der Liga.","en":"Our goalkeeper is the best in the league.","ru":"Наш вратарь — лучший в лиге.","vi":"Thủ môn của chúng tôi là người giỏi nhất giải đấu.","fa":"دروازه بان ما بهترین در لیگ است."},{"de":"Der Torwart sprang in die linke Ecke.","en":"The goalkeeper dived into the left corner.","ru":"Вратарь бросился в левый угол.","vi":"Thủ môn nhảy vào góc trái.","fa":"دروازه بان به گوشه چپ پرید."}]},{"word":"tot","en":"dead","ru":"мёртвый","vi":"đã chết","fa":"مرده","examples":[{"de":"Die Pflanze ist leider tot.","en":"The plant is unfortunately dead.","ru":"К сожалению, растение погибло.","vi":"Thật không may là cây đã chết.","fa":"متأسفانه گیاه مرده است."},{"de":"Der Vogel lag tot auf der Straße.","en":"The bird lay dead on the street.","ru":"Птица лежала мёртвой на дороге.","vi":"Con chim nằm chết trên đường phố.","fa":"پرنده مرده در خیابان افتاده بود."}]},{"word":"total","en":"totally, completely","ru":"совершенно, полностью","vi":"hoàn toàn","fa":"کاملا","examples":[{"de":"Ich bin total müde.","en":"I am totally tired.","ru":"Я совершенно устал.","vi":"Tôi hoàn toàn mệt mỏi.","fa":"من کلا خسته ام"},{"de":"Das Konzert war total überfüllt.","en":"The concert was totally crowded.","ru":"Концерт был совершенно переполнен.","vi":"Buổi hòa nhạc hoàn toàn đông đúc.","fa":"کنسرت کاملا شلوغ بود."}]},{"word":"der Tote","en":"dead person, casualty","ru":"погибший, покойник","vi":"người đàn ông đã chết","fa":"مرد مرده","examples":[{"de":"Bei dem Unfall gab es leider mehrere Tote.","en":"Sadly there were several fatalities in the accident.","ru":"К сожалению, в аварии было несколько погибших.","vi":"Thật không may, đã có một số người chết trong vụ tai nạn.","fa":"متأسفانه در این حادثه چندین کشته برجای گذاشت."},{"de":"Die Polizei fand den Toten im Wald.","en":"The police found the dead man in the forest.","ru":"Полиция нашла погибшего мужчину в лесу.","vi":"Cảnh sát tìm thấy người đàn ông chết trong rừng.","fa":"پلیس مرد مرده را در جنگل پیدا کرد."},{"de":"Man gedachte der Toten mit einer Schweigeminute.","en":"They remembered the dead with a minute of silence.","ru":"Погибших почтили минутой молчания.","vi":"Người chết được tưởng nhớ bằng một phút im lặng.","fa":"یاد و خاطره شهدا با یک دقیقه سکوت برگزار شد."}]},{"word":"der Tourismus","en":"tourism","ru":"туризм","vi":"du lịch","fa":"گردشگری","examples":[{"de":"Der Tourismus ist wichtig für die Wirtschaft der Stadt.","en":"Tourism is important for the city's economy.","ru":"Туризм важен для экономики города.","vi":"Du lịch rất quan trọng đối với nền kinh tế của thành phố.","fa":"گردشگری برای اقتصاد شهر مهم است."},{"de":"Der Tourismus hat in den letzten Jahren stark zugenommen.","en":"Tourism has increased sharply in recent years.","ru":"Туризм значительно вырос за последние годы.","vi":"Du lịch đã tăng lên đáng kể trong những năm gần đây.","fa":"گردشگری در سال های اخیر افزایش چشمگیری داشته است."}]},{"word":"die Tradition","en":"tradition","ru":"традиция","vi":"truyền thống","fa":"سنت","examples":[{"de":"Diese Tradition wird seit Generationen gepflegt.","en":"This tradition has been kept for generations.","ru":"Эта традиция поддерживается на протяжении поколений.","vi":"Truyền thống này đã được duy trì qua nhiều thế hệ.","fa":"این سنت برای نسل ها حفظ شده است."},{"de":"Es ist eine alte Tradition, zu Weihnachten einen Baum aufzustellen.","en":"It is an old tradition to put up a tree at Christmas.","ru":"Ставить ёлку на Рождество — старая традиция.","vi":"Việc dựng cây thông vào dịp Giáng sinh là một truyền thống lâu đời.","fa":"کاشتن درخت در کریسمس یک سنت قدیمی است."}]},{"word":"traditionell","en":"traditional","ru":"традиционный","vi":"truyền thống","fa":"سنتی","examples":[{"de":"Zu Weihnachten essen wir traditionell Gans.","en":"At Christmas we traditionally eat goose.","ru":"На Рождество мы традиционно едим гуся.","vi":"Theo truyền thống, chúng ta ăn ngỗng vào dịp Giáng sinh.","fa":"ما به طور سنتی در کریسمس غاز می خوریم."},{"de":"Das ist ein traditionelles deutsches Gericht.","en":"This is a traditional German dish.","ru":"Это традиционное немецкое блюдо.","vi":"Đây là món ăn truyền thống của Đức.","fa":"این یک غذای سنتی آلمانی است."},{"de":"Die Hochzeit war sehr traditionell.","en":"The wedding was very traditional.","ru":"Свадьба была очень традиционной.","vi":"Đám cưới rất truyền thống.","fa":"عروسی خیلی سنتی بود."}]},{"word":"tragen","en":"to carry; to wear","ru":"нести; носить","vi":"mặc","fa":"پوشیدن","examples":[{"de":"Er trägt die schweren Taschen in die Wohnung.","en":"He carries the heavy bags into the apartment.","ru":"Он несёт тяжёлые сумки в квартиру.","vi":"Anh xách những chiếc túi nặng nề vào căn hộ.","fa":"او کیسه های سنگین را به داخل آپارتمان می برد."},{"de":"Sie trägt heute ein rotes Kleid.","en":"She is wearing a red dress today.","ru":"Сегодня она носит красное платье.","vi":"Hôm nay cô ấy mặc một chiếc váy màu đỏ.","fa":"او امروز یک لباس قرمز پوشیده است."}]},{"word":"die Trägheit","en":"inertia","ru":"инертность, инерция","vi":"quán tính","fa":"اینرسی","examples":[{"de":"Wegen der Trägheit fahren wir bei einer Vollbremsung nach vorne.","en":"Because of inertia we are thrown forward when the car brakes hard.","ru":"Из-за инерции при резком торможении нас бросает вперёд.","vi":"Do quán tính nên chúng ta tiến về phía trước khi phanh gấp.","fa":"به دلیل اینرسی، هنگام ترمز شدید به جلو حرکت می کنیم."},{"de":"Die Trägheit eines Körpers hängt von seiner Masse ab.","en":"The inertia of a body depends on its mass.","ru":"Инертность тела зависит от его массы.","vi":"Quán tính của một vật phụ thuộc vào khối lượng của nó.","fa":"اینرسی جسم به جرم آن بستگی دارد."},{"de":"Ohne eine Kraft bleibt ein Körper aufgrund seiner Trägheit in Ruhe.","en":"Without a force a body stays at rest because of its inertia.","ru":"Без силы тело остаётся в покое из-за своей инертности.","vi":"Không có lực, vật vẫn đứng yên nhờ quán tính của nó.","fa":"بدون نیرو، جسم به دلیل اینرسی خود در حالت سکون باقی می ماند."}]},{"word":"der Trainer","en":"coach, trainer (male)","ru":"тренер (мужчина)","vi":"huấn luyện viên","fa":"مربی","examples":[{"de":"Der Trainer lobte die Mannschaft für ihr gutes Spiel.","en":"The coach praised the team for their good game.","ru":"Тренер похвалил команду за хорошую игру.","vi":"Huấn luyện viên khen ngợi đội đã chơi tốt.","fa":"سرمربی تیم از بازی خوبشان تمجید کرد."},{"de":"Unser neuer Trainer ist sehr streng.","en":"Our new coach is very strict.","ru":"Наш новый тренер очень строгий.","vi":"Huấn luyện viên mới của chúng tôi rất nghiêm khắc.","fa":"مربی جدید ما خیلی سخت گیر است."},{"de":"Der Trainer gibt jeden Dienstag ein Training.","en":"The trainer holds a training session every Tuesday.","ru":"Тренер проводит тренировку каждый вторник.","vi":"Huấn luyện viên tổ chức buổi tập vào thứ Ba hàng tuần.","fa":"مربی هر سه شنبه یک جلسه تمرینی برگزار می کند."}]},{"word":"die Trainerin","en":"coach, trainer (female)","ru":"тренер (женщина)","vi":"huấn luyện viên","fa":"مربی","examples":[{"de":"Die Trainerin erklärte uns die neuen Übungen.","en":"The trainer explained the new exercises to us.","ru":"Тренер объяснила нам новые упражнения.","vi":"Huấn luyện viên giải thích các bài tập mới cho chúng tôi.","fa":"مربی تمرینات جدید را برای ما توضیح داد."},{"de":"Unsere Trainerin hat selbst früher professionell gespielt.","en":"Our coach used to play professionally herself.","ru":"Наша тренер раньше сама играла профессионально.","vi":"Huấn luyện viên của chúng tôi từng thi đấu chuyên nghiệp.","fa":"مربی ما خودش حرفه ای بازی می کرد."},{"de":"Die Trainerin motiviert die Spielerinnen jeden Tag.","en":"The coach motivates the players every day.","ru":"Тренер каждый день мотивирует игроков.","vi":"Huấn luyện viên động viên các cầu thủ mỗi ngày.","fa":"مربی هر روز به بازیکنان انگیزه می دهد."}]},{"word":"trainieren","en":"to train, to practice","ru":"тренироваться","vi":"xe lửa","fa":"قطار","examples":[{"de":"Er trainiert jeden Tag im Fitnessstudio.","en":"He trains every day at the gym.","ru":"Он тренируется каждый день в спортзале.","vi":"Anh ấy tập luyện ở phòng gym mỗi ngày.","fa":"او هر روز در باشگاه تمرین می کند."},{"de":"Die Mannschaft trainiert für das nächste Spiel.","en":"The team is training for the next game.","ru":"Команда тренируется к следующей игре.","vi":"Toàn đội đang tập luyện cho trận đấu tiếp theo.","fa":"این تیم برای بازی بعدی تمرین می کند."}]},{"word":"die Tram","en":"tram","ru":"трамвай","vi":"xe điện","fa":"تراموا","examples":[{"de":"Ich fahre jeden Morgen mit der Tram zur Arbeit.","en":"I take the tram to work every morning.","ru":"Каждое утро я езжу на работу на трамвае.","vi":"Tôi đi xe điện đi làm mỗi sáng.","fa":"من هر روز صبح با تراموا سر کار می روم."},{"de":"Die Tram hält direkt vor dem Bahnhof.","en":"The tram stops right in front of the station.","ru":"Трамвай останавливается прямо перед вокзалом.","vi":"Xe điện dừng ngay trước ga xe lửa.","fa":"تراموا درست در مقابل ایستگاه قطار توقف می کند."},{"de":"In dieser Stadt fährt die Tram alle zehn Minuten.","en":"In this city the tram runs every ten minutes.","ru":"В этом городе трамвай ходит каждые десять минут.","vi":"Ở thành phố này, xe điện chạy cứ mười phút một lần.","fa":"در این شهر تراموا هر ده دقیقه یکبار حرکت می کند."}]},{"word":"die Träne","en":"tear","ru":"слеза","vi":"nước mắt","fa":"اشک","examples":[{"de":"Ihr liefen die Tränen über das Gesicht.","en":"Tears ran down her face.","ru":"Слёзы текли по её лицу.","vi":"Nước mắt chảy dài trên khuôn mặt cô.","fa":"اشک روی صورتش جاری بود."},{"de":"Er konnte seine Tränen nicht zurückhalten.","en":"He couldn't hold back his tears.","ru":"Он не мог сдержать слёзы.","vi":"Anh không thể cầm được nước mắt.","fa":"نتوانست جلوی اشک هایش را بگیرد."}]},{"word":"der Transport","en":"transport, transportation","ru":"перевозка, транспортировка","vi":"vận chuyển","fa":"حمل و نقل","examples":[{"de":"Der Transport der Möbel hat länger gedauert als geplant.","en":"The transport of the furniture took longer than planned.","ru":"Перевозка мебели заняла больше времени, чем планировалось.","vi":"Việc vận chuyển đồ đạc mất nhiều thời gian hơn dự kiến.","fa":"حمل و نقل اثاثیه بیش از برنامه ریزی شده طول کشید."},{"de":"Für den Transport großer Geräte brauchen wir einen Lieferwagen.","en":"For the transport of large appliances we need a delivery van.","ru":"Для перевозки крупной техники нам нужен грузовой фургон.","vi":"Chúng tôi cần một chiếc xe tải để vận chuyển thiết bị lớn.","fa":"به یک وانت جهت حمل وسایل بزرگ نیازمندیم."},{"de":"Während des Transports ist leider eine Vase zerbrochen.","en":"During transport a vase unfortunately broke.","ru":"Во время перевозки, к сожалению, разбилась ваза.","vi":"Thật không may một chiếc bình đã bị vỡ trong quá trình vận chuyển.","fa":"متاسفانه یک گلدان در حین حمل شکست."}]},{"word":"transportieren","en":"to transport","ru":"перевозить, транспортировать","vi":"vận chuyển","fa":"حمل و نقل","examples":[{"de":"Der Lkw transportiert Möbel in die neue Stadt.","en":"The truck transports furniture to the new city.","ru":"Грузовик перевозит мебель в новый город.","vi":"Xe tải chở đồ đạc vào thành phố mới.","fa":"کامیون اثاثیه را به شهر جدید حمل می کند."},{"de":"Die Waren werden per Schiff transportiert.","en":"The goods are transported by ship.","ru":"Товары перевозятся на корабле.","vi":"Hàng hóa được vận chuyển bằng tàu.","fa":"حمل و نقل کالا با کشتی انجام می شود."}]},{"word":"die Trauer","en":"grief; mourning","ru":"скорбь; печаль","vi":"nỗi buồn","fa":"غم و اندوه","examples":[{"de":"Nach dem Verlust brauchte sie Zeit für ihre Trauer.","en":"After the loss she needed time for her grief.","ru":"После утраты ей было нужно время для скорби.","vi":"Sau mất mát, cô cần thời gian để đau buồn.","fa":"پس از فقدان، او به زمان نیاز داشت تا غصه بخورد."},{"de":"Die ganze Stadt war in Trauer.","en":"The whole town was in mourning.","ru":"Весь город был в трауре.","vi":"Cả thành phố chìm trong tang thương.","fa":"تمام شهر در ماتم بود."}]},{"word":"träumen","en":"to dream","ru":"мечтать, видеть сны","vi":"giấc mơ","fa":"رویا","examples":[{"de":"Letzte Nacht habe ich von meiner Kindheit geträumt.","en":"Last night I dreamed about my childhood.","ru":"Прошлой ночью мне снилось моё детство.","vi":"Đêm qua tôi mơ về tuổi thơ của mình.","fa":"دیشب خواب کودکی ام را دیدم."},{"de":"Sie träumt davon, einmal die Welt zu bereisen.","en":"She dreams of traveling the world someday.","ru":"Она мечтает когда-нибудь путешествовать по миру.","vi":"Cô mơ ước một ngày được đi du lịch khắp thế giới.","fa":"او آرزو دارد روزی به دور دنیا سفر کند."}]},{"word":"traumhaft","en":"dreamlike, wonderful, gorgeous","ru":"сказочный, чудесный, восхитительный","vi":"tuyệt vời","fa":"فوق العاده","examples":[{"de":"Wir hatten einen traumhaften Urlaub am Meer.","en":"We had a wonderful holiday by the sea.","ru":"У нас был чудесный отпуск у моря.","vi":"Chúng tôi đã có một kỳ nghỉ tuyệt vời bên bờ biển.","fa":"تعطیلات فوق العاده ای در کنار دریا داشتیم."},{"de":"Das Wetter war traumhaft schön.","en":"The weather was gorgeously beautiful.","ru":"Погода была сказочно прекрасной.","vi":"Thời tiết đẹp vô cùng.","fa":"هوا فوق العاده زیبا بود."},{"de":"Von hier hat man einen traumhaften Blick auf die Berge.","en":"From here you have a dreamlike view of the mountains.","ru":"Отсюда открывается сказочный вид на горы.","vi":"Từ đây bạn có một cái nhìn tuyệt vời về những ngọn núi.","fa":"از اینجا منظره فوق العاده ای از کوه ها خواهید داشت."}]},{"word":"traurig","en":"sad","ru":"грустный","vi":"buồn","fa":"غمگین","examples":[{"de":"Nach dem Abschied war sie sehr traurig.","en":"After the farewell she was very sad.","ru":"После прощания она была очень грустной.","vi":"Sau khi chia tay, cô ấy rất buồn.","fa":"بعد از خداحافظی خیلی ناراحت شد."},{"de":"Der traurige Film hat mich zum Weinen gebracht.","en":"The sad movie made me cry.","ru":"Грустный фильм заставил меня плакать.","vi":"Bộ phim buồn đã làm tôi khóc.","fa":"فیلم غمگین مرا به گریه انداخت."}]},{"word":"treffen","en":"to meet","ru":"встречать(ся)","vi":"gặp gỡ","fa":"ملاقات کنید","examples":[{"de":"Ich treffe meine Freunde heute Abend.","en":"I am meeting my friends tonight.","ru":"Я встречаюсь с друзьями сегодня вечером.","vi":"Tôi sẽ gặp bạn bè của tôi tối nay.","fa":"من امروز عصر با دوستانم ملاقات می کنم."},{"de":"Wir haben uns zufällig in der Stadt getroffen.","en":"We met by chance in the city.","ru":"Мы случайно встретились в городе.","vi":"Chúng tôi tình cờ gặp nhau ở thành phố.","fa":"به طور اتفاقی در شهر با هم آشنا شدیم."}]},{"word":"der Treffpunkt","en":"meeting point, rendezvous","ru":"место встречи","vi":"điểm gặp gỡ","fa":"نقطه ملاقات","examples":[{"de":"Unser Treffpunkt ist der Brunnen vor dem Bahnhof.","en":"Our meeting point is the fountain in front of the station.","ru":"Наше место встречи — фонтан перед вокзалом.","vi":"Điểm hẹn của chúng tôi là đài phun nước trước ga xe lửa.","fa":"نقطه ملاقات ما فواره روبروی ایستگاه قطار است."},{"de":"Wir haben um acht Uhr einen Treffpunkt am Eingang vereinbart.","en":"We arranged a meeting point at the entrance for eight o'clock.","ru":"Мы договорились о месте встречи у входа на восемь часов.","vi":"Chúng tôi đồng ý gặp nhau ở lối vào lúc 8 giờ.","fa":"قرار گذاشتیم ساعت هشت در ورودی همدیگر را ببینیم."},{"de":"Das Café ist ein beliebter Treffpunkt für Studenten.","en":"The café is a popular meeting point for students.","ru":"Кафе — популярное место встречи студентов.","vi":"Quán cà phê là nơi gặp gỡ quen thuộc của sinh viên.","fa":"این کافه محل ملاقات محبوب دانشجویان است."}]},{"word":"treiben","en":"to do (sports); to drive, to push","ru":"заниматься (спортом); гнать","vi":"lái xe","fa":"رانندگی کنید","examples":[{"de":"Er treibt regelmäßig Sport.","en":"He does sports regularly.","ru":"Он регулярно занимается спортом.","vi":"Anh ấy tập thể dục thường xuyên.","fa":"او به طور منظم ورزش می کند."},{"de":"Der Wind trieb die Wolken über den Himmel.","en":"The wind drove the clouds across the sky.","ru":"Ветер гнал облака по небу.","vi":"Gió đưa mây bay khắp trời.","fa":"باد ابرها را در آسمان می راند."}]},{"word":"der Treibhausgasausstoß","en":"greenhouse gas emissions","ru":"выбросы парниковых газов","vi":"phát thải khí nhà kính","fa":"انتشار گازهای گلخانه ای","examples":[{"de":"Der Treibhausgasausstoß muss in den nächsten Jahren sinken.","en":"Greenhouse gas emissions must fall in the coming years.","ru":"Выбросы парниковых газов должны снизиться в ближайшие годы.","vi":"Lượng khí thải nhà kính phải giảm trong vài năm tới.","fa":"انتشار گازهای گلخانه ای باید در چند سال آینده کاهش یابد."},{"de":"Der Verkehr verursacht einen großen Treibhausgasausstoß.","en":"Traffic causes a large amount of greenhouse gas emissions.","ru":"Транспорт вызывает большие выбросы парниковых газов.","vi":"Giao thông vận tải gây ra lượng khí thải nhà kính lớn.","fa":"حمل و نقل باعث انتشار گازهای گلخانه ای بزرگ می شود."},{"de":"Viele Länder wollen ihren Treibhausgasausstoß halbieren.","en":"Many countries want to halve their greenhouse gas emissions.","ru":"Многие страны хотят вдвое сократить свои выбросы парниковых газов.","vi":"Nhiều quốc gia muốn giảm một nửa lượng khí thải nhà kính.","fa":"بسیاری از کشورها می خواهند انتشار گازهای گلخانه ای خود را به نصف کاهش دهند."}]},{"word":"der Trend","en":"trend","ru":"тренд","vi":"xu hướng","fa":"روند","examples":[{"de":"Die Daten zeigen einen klaren Trend nach oben.","en":"The data show a clear upward trend.","ru":"Данные показывают чёткий восходящий тренд.","vi":"Dữ liệu cho thấy một xu hướng tăng rõ ràng.","fa":"داده ها روند صعودی واضحی را نشان می دهد."},{"de":"Wir erkennen einen Trend zu mehr Online-Käufen.","en":"We see a trend towards more online purchases.","ru":"Мы видим тренд к росту онлайн-покупок.","vi":"Chúng tôi đang thấy xu hướng mua hàng trực tuyến nhiều hơn.","fa":"ما شاهد روند خریدهای آنلاین بیشتر هستیم."},{"de":"Der Trend hat sich in den letzten Monaten umgekehrt.","en":"The trend has reversed in recent months.","ru":"Тренд в последние месяцы развернулся.","vi":"Xu hướng này đã đảo ngược trong những tháng gần đây.","fa":"این روند در ماه های اخیر معکوس شده است."}]},{"word":"trennen","en":"to separate, to sort (waste)","ru":"разделять, сортировать (мусор)","vi":"riêng biệt","fa":"جدا کردن","examples":[{"de":"In Deutschland muss man den Müll trennen.","en":"In Germany you have to separate your rubbish.","ru":"В Германии мусор нужно сортировать.","vi":"Ở Đức bạn phải phân loại rác.","fa":"در آلمان باید زباله ها را جدا کرد."},{"de":"Papier und Glas sollte man getrennt sammeln.","en":"Paper and glass should be collected separately.","ru":"Бумагу и стекло следует собирать раздельно.","vi":"Giấy và thủy tinh phải được thu gom riêng.","fa":"کاغذ و شیشه باید جداگانه جمع آوری شوند."},{"de":"Kannst du bitte den Biomüll vom Restmüll trennen?","en":"Can you please separate the bio-waste from the general waste?","ru":"Можешь, пожалуйста, отделить биоотходы от общего мусора?","vi":"Bạn có thể vui lòng tách chất thải hữu cơ khỏi chất thải còn lại?","fa":"آیا می توانید زباله های آلی را از زباله های باقیمانده جدا کنید؟"}]},{"word":"die Trennung","en":"separation; break-up","ru":"разлука; расставание","vi":"sự chia ly","fa":"جدایی","examples":[{"de":"Nach der Trennung zog er in eine andere Stadt.","en":"After the break-up he moved to another city.","ru":"После расставания он переехал в другой город.","vi":"Sau khi chia tay, anh chuyển đến thành phố khác.","fa":"پس از جدایی به شهر دیگری نقل مکان کرد."},{"de":"Die Trennung von den Kindern fiel ihr sehr schwer.","en":"The separation from the children was very hard for her.","ru":"Разлука с детьми далась ей очень тяжело.","vi":"Việc cô phải xa các con là điều vô cùng khó khăn.","fa":"جدا شدن از فرزندانش برایش خیلی سخت بود."}]},{"word":"die Treppe","en":"stairs, staircase","ru":"лестница","vi":"cầu thang","fa":"پله ها","examples":[{"de":"Die Treppe führt in den zweiten Stock.","en":"The stairs lead to the second floor.","ru":"Лестница ведёт на третий этаж.","vi":"Cầu thang dẫn lên tầng hai.","fa":"پله ها به طبقه دوم منتهی می شوند."},{"de":"Sei vorsichtig auf der Treppe, sie ist rutschig.","en":"Be careful on the stairs, they are slippery.","ru":"Будь осторожен на лестнице, она скользкая.","vi":"Hãy cẩn thận trên cầu thang, chúng trơn trượt.","fa":"مراقب پله ها باشید، آنها لیز هستند."}]},{"word":"das Treppenhaus","en":"stairwell","ru":"лестничная клетка","vi":"cầu thang","fa":"راه پله","examples":[{"de":"Das Treppenhaus ist alt, aber gut beleuchtet.","en":"The stairwell is old but well lit.","ru":"Лестничная клетка старая, но хорошо освещена.","vi":"Cầu thang đã cũ nhưng đủ ánh sáng.","fa":"راه پله قدیمی است اما نور خوبی دارد."},{"de":"Im Treppenhaus riecht es nach frischer Farbe.","en":"The stairwell smells of fresh paint.","ru":"В подъезде пахнет свежей краской.","vi":"Cầu thang thơm mùi sơn mới.","fa":"راه پله بوی رنگ تازه می دهد."}]},{"word":"treten","en":"to step; to kick","ru":"наступать; пинать","vi":"cú đá","fa":"لگد زدن","examples":[{"de":"Pass auf, dass du nicht in die Pfütze trittst.","en":"Be careful not to step in the puddle.","ru":"Осторожно, не наступи в лужу.","vi":"Hãy cẩn thận đừng bước vào vũng nước.","fa":"مراقب باشید وارد گودال نشوید."},{"de":"Der Spieler hat den Ball ins Tor getreten.","en":"The player kicked the ball into the goal.","ru":"Игрок ударом отправил мяч в ворота.","vi":"Cầu thủ này đã sút bóng vào khung thành.","fa":"بازیکن توپ را وارد دروازه کرد."}]},{"word":"treu","en":"faithful, loyal","ru":"верный","vi":"trung thành","fa":"وفادار","examples":[{"de":"Ein Hund ist ein treuer Freund.","en":"A dog is a loyal friend.","ru":"Собака — верный друг.","vi":"Một con chó là một người bạn trung thành.","fa":"سگ یک دوست وفادار است."},{"de":"Sie war ihrem Mann immer treu.","en":"She was always faithful to her husband.","ru":"Она всегда была верна своему мужу.","vi":"Cô luôn chung thủy với chồng.","fa":"او همیشه به شوهرش وفادار بود."}]},{"word":"trinkbar","en":"drinkable","ru":"пригодный для питья, питьевой","vi":"có thể uống được","fa":"قابل نوشیدن","examples":[{"de":"Das Wasser hier ist trinkbar.","en":"The water here is drinkable.","ru":"Вода здесь пригодна для питья.","vi":"Nước ở đây có thể uống được.","fa":"آب اینجا قابل شرب است."},{"de":"Ist das Leitungswasser hier trinkbar?","en":"Is the tap water here drinkable?","ru":"Здешняя водопроводная вода пригодна для питья?","vi":"Nước máy ở đây có uống được không?","fa":"آیا آب لوله کشی اینجا قابل شرب است؟"},{"de":"Nach der Reinigung ist das Wasser wieder trinkbar.","en":"After purification the water is drinkable again.","ru":"После очистки вода снова пригодна для питья.","vi":"Sau khi làm sạch, nước có thể uống được trở lại.","fa":"پس از تمیز کردن، آب دوباره قابل شرب است."}]},{"word":"trinken","en":"to drink","ru":"пить","vi":"uống","fa":"نوشیدنی","examples":[{"de":"Ich trinke jeden Tag viel Wasser.","en":"I drink a lot of water every day.","ru":"Я пью много воды каждый день.","vi":"Tôi uống rất nhiều nước mỗi ngày.","fa":"من هر روز مقدار زیادی آب می نوشم."},{"de":"Möchtest du etwas trinken?","en":"Would you like something to drink?","ru":"Хочешь что-нибудь выпить?","vi":"Bạn có muốn uống gì không?","fa":"آیا می خواهید چیزی بنوشید؟"}]},{"word":"das Trinkgeld","en":"tip, gratuity","ru":"чаевые","vi":"tiền boa","fa":"نوک","examples":[{"de":"In Deutschland gibt man im Restaurant oft etwas Trinkgeld.","en":"In Germany you often give a small tip in a restaurant.","ru":"В Германии в ресторане часто оставляют небольшие чаевые.","vi":"Ở Đức bạn thường đưa tiền boa trong nhà hàng.","fa":"در آلمان اغلب در رستوران انعام می دهید."},{"de":"Der Kellner hat sich über das großzügige Trinkgeld gefreut.","en":"The waiter was pleased about the generous tip.","ru":"Официант обрадовался щедрым чаевым.","vi":"Người phục vụ rất vui vì tiền boa hào phóng.","fa":"گارسون از انعام سخاوتمندانه خوشحال شد."},{"de":"Wie viel Trinkgeld gibst du dem Taxifahrer?","en":"How much tip do you give the taxi driver?","ru":"Сколько чаевых ты даёшь таксисту?","vi":"Bạn tip tài xế taxi bao nhiêu?","fa":"چقدر به راننده تاکسی انعام می دهید؟"}]},{"word":"trocken","en":"dry","ru":"сухой","vi":"khô","fa":"خشک","examples":[{"de":"Im Sommer ist das Wetter hier sehr trocken.","en":"In summer the weather here is very dry.","ru":"Летом погода здесь очень сухая.","vi":"Vào mùa hè thời tiết ở đây rất khô.","fa":"در تابستان هوای اینجا بسیار خشک است."},{"de":"Die Wäsche ist schon trocken.","en":"The laundry is already dry.","ru":"Бельё уже высохло.","vi":"Đồ giặt đã khô rồi.","fa":"لباسشویی در حال حاضر خشک شده است."}]},{"word":"die Trockenperiode","en":"dry spell, period of drought","ru":"период засухи, засушливый период","vi":"thời kỳ khô hạn","fa":"دوره خشکی","examples":[{"de":"Die lange Trockenperiode schadete der Ernte.","en":"The long dry spell damaged the harvest.","ru":"Долгий период засухи повредил урожаю.","vi":"Thời gian khô hạn kéo dài làm hỏng vụ thu hoạch.","fa":"دوره طولانی خشکی به برداشت آسیب زد."},{"de":"Während der Trockenperiode sank der Wasserstand der Flüsse.","en":"During the dry spell the water level of the rivers fell.","ru":"Во время засухи уровень воды в реках упал.","vi":"Trong thời kỳ khô hạn, mực nước các sông giảm xuống.","fa":"در دوره خشکی، سطح آب رودخانه ها کاهش یافت."},{"de":"Solche Trockenperioden werden durch den Klimawandel häufiger.","en":"Such dry spells are becoming more frequent due to climate change.","ru":"Такие засушливые периоды становятся чаще из-за изменения климата.","vi":"Những thời kỳ khô hạn như vậy đang trở nên thường xuyên hơn do biến đổi khí hậu.","fa":"چنین دوره های خشکی به دلیل تغییرات آب و هوایی بیشتر می شود."}]},{"word":"trocknen","en":"to dry","ru":"сушить, сохнуть","vi":"khô","fa":"خشک","examples":[{"de":"Ich hänge die Wäsche zum Trocknen auf.","en":"I hang the laundry up to dry.","ru":"Я вешаю бельё сушиться.","vi":"Tôi treo đồ giặt lên cho khô.","fa":"لباس‌ها را آویزان می‌کنم تا خشک شوند."},{"de":"Die Haare trocknen schnell in der Sonne.","en":"Hair dries quickly in the sun.","ru":"Волосы быстро сохнут на солнце.","vi":"Tóc khô nhanh dưới ánh nắng mặt trời.","fa":"موها در آفتاب به سرعت خشک می شوند."}]},{"word":"die Tropfen","en":"drops (medicine)","ru":"капли (лекарство)","vi":"những giọt","fa":"قطره ها","examples":[{"de":"Nimm dreimal täglich zehn Tropfen von dieser Medizin.","en":"Take ten drops of this medicine three times a day.","ru":"Принимай по десять капель этого лекарства три раза в день.","vi":"Uống mười giọt thuốc này ba lần một ngày.","fa":"ده قطره از این دارو را سه بار در روز میل کنید."},{"de":"Der Arzt hat mir Tropfen gegen den Husten verschrieben.","en":"The doctor prescribed me drops for the cough.","ru":"Врач прописал мне капли от кашля.","vi":"Bác sĩ kê cho tôi thuốc nhỏ trị ho.","fa":"دکتر برای من قطره برای سرفه تجویز کرد."}]},{"word":"trösten","en":"to comfort, to console","ru":"утешать","vi":"sự thoải mái","fa":"راحتی","examples":[{"de":"Die Mutter tröstet ihr weinendes Kind.","en":"The mother is comforting her crying child.","ru":"Мать утешает своего плачущего ребёнка.","vi":"Người mẹ an ủi đứa con đang khóc.","fa":"مادر به کودک گریانش دلداری می دهد."},{"de":"Es tröstet mich, dass du an mich denkst.","en":"It comforts me that you are thinking of me.","ru":"Меня утешает то, что ты думаешь обо мне.","vi":"Tôi an ủi rằng bạn đang nghĩ đến tôi.","fa":"این که به من فکر می کنی به من آرامش می دهد."},{"de":"Sie versuchte, ihre traurige Freundin zu trösten.","en":"She tried to console her sad friend.","ru":"Она пыталась утешить свою грустную подругу.","vi":"Cô cố gắng an ủi người bạn đang buồn bã của mình.","fa":"سعی کرد به دوست غمگینش دلداری دهد."}]},{"word":"das Trottoir","en":"sidewalk, pavement","ru":"тротуар","vi":"vỉa hè","fa":"پیاده رو","examples":[{"de":"Die Kinder fahren mit dem Fahrrad auf dem Trottoir.","en":"The children ride their bikes on the sidewalk.","ru":"Дети катаются на велосипеде по тротуару.","vi":"Trẻ em đạp xe trên vỉa hè.","fa":"بچه ها در پیاده رو دوچرخه سواری می کنند."},{"de":"Parken auf dem Trottoir ist verboten.","en":"Parking on the sidewalk is prohibited.","ru":"Парковка на тротуаре запрещена.","vi":"Cấm đậu xe trên vỉa hè.","fa":"پارک کردن در پیاده رو ممنوع است."}]},{"word":"trotz","en":"despite, in spite of","ru":"несмотря на","vi":"mặc dù","fa":"با وجود","examples":[{"de":"Trotz des schlechten Wetters gingen wir spazieren.","en":"Despite the bad weather, we went for a walk.","ru":"Несмотря на плохую погоду, мы пошли гулять.","vi":"Mặc dù thời tiết xấu, chúng tôi vẫn đi dạo.","fa":"با وجود بدی هوا رفتیم پیاده روی."},{"de":"Trotz seiner Krankheit arbeitet er weiter.","en":"Despite his illness, he keeps working.","ru":"Несмотря на свою болезнь, он продолжает работать.","vi":"Bất chấp bệnh tật, anh vẫn tiếp tục làm việc.","fa":"او با وجود بیماری به کار خود ادامه می دهد."}]},{"word":"trotzdem","en":"nevertheless, still","ru":"тем не менее, всё же","vi":"dù sao đi nữa","fa":"به هر حال","examples":[{"de":"Es regnete stark, trotzdem gingen wir raus.","en":"It was raining hard, but we went out anyway.","ru":"Шёл сильный дождь, но мы всё равно пошли гулять.","vi":"Trời mưa rất to nhưng chúng tôi vẫn đi ra ngoài.","fa":"باران شدیدی می بارید، اما به هر حال ما بیرون رفتیم."},{"de":"Sie war müde, trotzdem lernte sie weiter.","en":"She was tired, nevertheless she kept studying.","ru":"Она устала, но всё равно продолжала учиться.","vi":"Cô mệt mỏi nhưng vẫn tiếp tục học.","fa":"خسته بود اما به درس خواندن ادامه داد."}]},{"word":"der Tsunami","en":"tsunami","ru":"цунами","vi":"sóng thần","fa":"سونامی","examples":[{"de":"Nach dem Erdbeben warnten die Behörden vor einem Tsunami.","en":"After the earthquake the authorities warned of a tsunami.","ru":"После землетрясения власти предупредили о цунами.","vi":"Sau trận động đất, chính quyền đã cảnh báo về sóng thần.","fa":"پس از زلزله، مقامات نسبت به وقوع سونامی هشدار دادند."},{"de":"Der Tsunami zerstörte viele Häuser an der Küste.","en":"The tsunami destroyed many houses on the coast.","ru":"Цунами разрушило много домов на побережье.","vi":"Sóng thần đã phá hủy nhiều ngôi nhà ven biển.","fa":"سونامی بسیاری از خانه ها را در ساحل ویران کرد."},{"de":"Ein Tsunami kann sich mit enormer Geschwindigkeit ausbreiten.","en":"A tsunami can spread at enormous speed.","ru":"Цунами может распространяться с огромной скоростью.","vi":"Một cơn sóng thần có thể lan rộng với tốc độ rất lớn.","fa":"سونامی می تواند با سرعت بسیار زیاد گسترش یابد."}]},{"word":"das Tuch","en":"cloth","ru":"платок, ткань","vi":"tấm vải","fa":"پارچه","examples":[{"de":"Sie wischt den Tisch mit einem feuchten Tuch ab.","en":"She wipes the table with a damp cloth.","ru":"Она вытирает стол влажной тряпкой.","vi":"Cô ấy lau bàn bằng một miếng vải ẩm.","fa":"میز را با یک پارچه مرطوب پاک می کند."},{"de":"Im Winter trägt sie ein warmes Tuch um den Hals.","en":"In winter she wears a warm scarf around her neck.","ru":"Зимой она носит тёплый платок на шее.","vi":"Vào mùa đông, cô quàng một chiếc khăn ấm quanh cổ.","fa":"در زمستان یک روسری گرم به گردن می اندازد."}]},{"word":"tun","en":"to do","ru":"делать","vi":"làm","fa":"انجام دهید","examples":[{"de":"Was tust du gerade?","en":"What are you doing right now?","ru":"Что ты сейчас делаешь?","vi":"Bây giờ bạn đang làm gì?","fa":"الان چیکار میکنی؟"},{"de":"Ich habe heute nichts zu tun.","en":"I have nothing to do today.","ru":"Мне сегодня нечего делать.","vi":"Hôm nay tôi không có gì để làm.","fa":"امروز کاری ندارم."}]},{"word":"die Tür","en":"door","ru":"дверь","vi":"cánh cửa","fa":"درب","examples":[{"de":"Bitte mach die Tür zu.","en":"Please close the door.","ru":"Пожалуйста, закрой дверь.","vi":"Hãy đóng cửa lại.","fa":"لطفا در را ببندید."},{"de":"Jemand klopft an der Tür.","en":"Someone is knocking on the door.","ru":"Кто-то стучит в дверь.","vi":"Có người gõ cửa.","fa":"یک نفر در را می زند."}]},{"word":"der Turm","en":"tower","ru":"башня","vi":"tòa tháp","fa":"برج","examples":[{"de":"Von dem Turm hat man eine tolle Aussicht.","en":"There is a great view from the tower.","ru":"С башни открывается прекрасный вид.","vi":"Bạn có một cái nhìn tuyệt vời từ tòa tháp.","fa":"از برج منظره عالی دارید."},{"de":"Der alte Turm der Kirche ist weithin sichtbar.","en":"The church's old tower is visible from afar.","ru":"Старая башня церкви видна издалека.","vi":"Tháp cũ của nhà thờ có thể nhìn thấy từ xa.","fa":"برج قدیمی کلیسا از دور نمایان است."}]},{"word":"das Turnier","en":"tournament","ru":"турнир","vi":"giải đấu","fa":"مسابقات","examples":[{"de":"Unsere Mannschaft hat das Turnier am Wochenende gewonnen.","en":"Our team won the tournament at the weekend.","ru":"Наша команда выиграла турнир на выходных.","vi":"Đội của chúng tôi đã thắng giải đấu vào cuối tuần.","fa":"تیم ما در آخر هفته قهرمان مسابقات شد."},{"de":"Am Turnier nahmen Spieler aus zehn Ländern teil.","en":"Players from ten countries took part in the tournament.","ru":"В турнире участвовали игроки из десяти стран.","vi":"Người chơi từ mười quốc gia đã tham gia giải đấu.","fa":"بازیکنانی از ده کشور در این مسابقات شرکت کردند."},{"de":"Das Tennisturnier wurde wegen des Regens verschoben.","en":"The tennis tournament was postponed because of the rain.","ru":"Теннисный турнир отложили из-за дождя.","vi":"Giải quần vợt bị hoãn do trời mưa.","fa":"مسابقات تنیس به دلیل بارندگی به تعویق افتاد."}]},{"word":"die Tüte","en":"bag (paper/plastic)","ru":"пакет","vi":"cái túi","fa":"کیف","examples":[{"de":"Kannst du mir bitte eine Tüte für die Einkäufe geben?","en":"Can you please give me a bag for the groceries?","ru":"Можешь дать мне пакет для покупок?","vi":"Bạn có thể vui lòng cho tôi một chiếc túi để mua sắm được không?","fa":"میشه لطفا یک کیف برای خرید به من بدهید؟"},{"de":"Die Tüte ist voller Äpfel.","en":"The bag is full of apples.","ru":"Пакет полон яблок.","vi":"Túi đầy táo.","fa":"کیسه پر از سیب است."}]},{"word":"twittern","en":"to tweet, to post on social media","ru":"твитить, писать в соцсети","vi":"tweet","fa":"توییت","examples":[{"de":"Der Politiker twittert fast jeden Tag.","en":"The politician tweets almost every day.","ru":"Политик твитит почти каждый день.","vi":"Chính trị gia này tweet gần như mỗi ngày.","fa":"این سیاستمدار تقریباً هر روز توییت می کند."},{"de":"Sie hat ein Foto von dem Konzert getwittert.","en":"She tweeted a photo from the concert.","ru":"Она затвитила фото с концерта.","vi":"Cô ấy đã tweet một bức ảnh từ buổi hòa nhạc.","fa":"او عکسی از کنسرت را توییت کرد."},{"de":"Viele junge Leute twittern lieber, als zu telefonieren.","en":"Many young people would rather tweet than make phone calls.","ru":"Многие молодые люди предпочитают твитить, а не звонить.","vi":"Nhiều người trẻ thích tweet hơn là gọi điện thoại.","fa":"بسیاری از جوانان ترجیح می دهند توییت کنند تا تماس تلفنی."}]},{"word":"der Typ","en":"guy; type","ru":"тип, парень","vi":"anh chàng","fa":"مرد","examples":[{"de":"Der Typ da drüben ist mein Nachbar.","en":"That guy over there is my neighbor.","ru":"Вон тот парень — мой сосед.","vi":"Anh chàng đằng kia là hàng xóm của tôi.","fa":"اون پسر اونجا همسایه منه"},{"de":"Welcher Typ von Auto gefällt dir am besten?","en":"Which type of car do you like best?","ru":"Какой тип машины тебе нравится больше всего?","vi":"Bạn thích loại xe nào nhất?","fa":"چه نوع ماشینی را بیشتر دوست دارید؟"}]},{"word":"die U-Bahn","en":"subway, underground (train)","ru":"метро","vi":"tàu điện ngầm","fa":"مترو","examples":[{"de":"Ich fahre jeden Tag mit der U-Bahn zur Arbeit.","en":"I take the subway to work every day.","ru":"Я каждый день езжу на работу на метро.","vi":"Tôi đi tàu điện ngầm đi làm hàng ngày.","fa":"من هر روز با مترو سر کار می روم."},{"de":"Die nächste U-Bahn kommt in fünf Minuten.","en":"The next subway train arrives in five minutes.","ru":"Следующий поезд метро прибудет через пять минут.","vi":"Chuyến tàu điện ngầm tiếp theo sẽ đến trong năm phút nữa.","fa":"متروی بعدی پنج دقیقه دیگر می رسد."}]},{"word":"üben","en":"to practice","ru":"тренироваться, упражняться","vi":"luyện tập","fa":"تمرین کنید","examples":[{"de":"Sie übt jeden Tag eine Stunde Klavier.","en":"She practices piano for an hour every day.","ru":"Она каждый день по часу упражняется на пианино.","vi":"Cô ấy tập piano một giờ mỗi ngày.","fa":"او هر روز یک ساعت پیانو تمرین می کند."},{"de":"Wir müssen die neuen Wörter noch üben.","en":"We still need to practice the new words.","ru":"Нам ещё нужно потренировать новые слова.","vi":"Chúng ta vẫn phải thực hành những từ mới.","fa":"ما هنوز باید کلمات جدید را تمرین کنیم."}]},{"word":"über","en":"over; about","ru":"над; о (чём-л.)","vi":"về","fa":"در مورد","examples":[{"de":"Das Bild hängt über dem Sofa.","en":"The picture hangs above the sofa.","ru":"Картина висит над диваном.","vi":"Bức tranh treo phía trên ghế sofa.","fa":"عکس بالای مبل آویزان است."},{"de":"Wir haben über das Wetter gesprochen.","en":"We talked about the weather.","ru":"Мы говорили о погоде.","vi":"Chúng tôi đã nói chuyện về thời tiết.","fa":"در مورد آب و هوا صحبت کردیم."}]},{"word":"über den eigenen Schatten springen","en":"to overcome one's inhibitions / step out of one's comfort zone","ru":"переступить через себя, преодолеть себя","vi":"vượt qua sự ức chế của một người / bước ra khỏi vùng thoải mái của một người","fa":"غلبه بر بازدارندگی ها / بیرون رفتن از منطقه آسایش","examples":[{"de":"Um sich zu entschuldigen, musste er über den eigenen Schatten springen.","en":"To apologise, he had to step out of his comfort zone.","ru":"Чтобы извиниться, ему пришлось переступить через себя.","vi":"Để xin lỗi, anh phải nhảy qua cái bóng của chính mình.","fa":"برای عذرخواهی مجبور شد از روی سایه خودش بپرد."}]},{"word":"über-","en":"over-, super- (prefix: excess or 'across')","ru":"над-, сверх-, пере- (приставка: избыток или «через»)","vi":"bên trên-","fa":"above-","examples":[{"de":"Das Vorsilbe 'über-' kann 'zu viel' bedeuten, wie in 'überlastet'.","en":"The prefix 'über-' can mean 'too much', as in 'overloaded'.","ru":"Приставка «über-» может означать «слишком много», как в «überlastet» (перегруженный).","vi":"Tiền tố 'over-' có thể có nghĩa là 'quá nhiều', như trong 'quá tải'.","fa":"پیشوند \"over-\" می تواند به معنای \"بیش از حد\" باشد، همانطور که در \"overloaded\"."},{"de":"Bei 'überqueren' bedeutet 'über-' so viel wie 'hinüber'.","en":"In 'überqueren' the prefix 'über-' means roughly 'across'.","ru":"В «überqueren» приставка «über-» значит примерно «через».","vi":"Khi nói đến 'vượt qua', 'over-' có nghĩa giống như 'over'.","fa":"وقتی صحبت از «عبور» می‌شود، «over-» به معنای چیزی شبیه «بیش از» است."},{"de":"Wörter wie 'übermüdet' zeigen ein Übermaß an.","en":"Words like 'übermüdet' (overtired) indicate an excess.","ru":"Слова вроде «übermüdet» (переутомлённый) указывают на избыток.","vi":"Những từ như 'mệt mỏi' biểu thị sự dư thừa.","fa":"کلماتی مانند \"خسته\" نشان دهنده زیاده روی است."}]},{"word":"überall","en":"everywhere","ru":"везде, повсюду","vi":"ở khắp mọi nơi","fa":"همه جا","examples":[{"de":"Überall liegt Schnee.","en":"Snow lies everywhere.","ru":"Везде лежит снег.","vi":"Có tuyết ở khắp mọi nơi.","fa":"همه جا برف است."},{"de":"Ich habe dich überall gesucht.","en":"I looked for you everywhere.","ru":"Я искал тебя везде.","vi":"Tôi đã tìm kiếm bạn khắp mọi nơi.","fa":"همه جا دنبالت گشتم"}]},{"word":"der Überblick","en":"overview","ru":"обзор, общее представление","vi":"tổng quan","fa":"نمای کلی","examples":[{"de":"Ich verschaffe mir einen Überblick.","en":"I am getting an overview.","ru":"Я составляю себе общее представление.","vi":"Tôi có được một cái nhìn tổng quan.","fa":"من یک نمای کلی دریافت می کنم."},{"de":"Die Tabelle gibt einen guten Überblick.","en":"The table gives a good overview.","ru":"Таблица даёт хороший обзор.","vi":"Bảng cung cấp một cái nhìn tổng quan tốt.","fa":"جدول نمای کلی خوبی ارائه می دهد."},{"de":"Er verlor den Überblick.","en":"He lost track of things.","ru":"Он потерял из виду общую картину.","vi":"Anh ấy đã mất dấu.","fa":"او مسیر را گم کرد."}]},{"word":"überfahren","en":"to run over (with a vehicle)","ru":"переехать (кого-л./что-л.)","vi":"chạy qua","fa":"فرار کردن","examples":[{"de":"Der Fahrer hat fast eine Katze überfahren.","en":"The driver almost ran over a cat.","ru":"Водитель чуть не переехал кошку.","vi":"Người lái xe suýt tông phải một con mèo.","fa":"نزدیک بود راننده به گربه برخورد کند."},{"de":"Pass auf, dass du niemanden überfährst!","en":"Watch out that you don't run anyone over!","ru":"Смотри, не переезжай никого!","vi":"Hãy cẩn thận để không chạy qua bất cứ ai!","fa":"مراقب باشید کسی را زیر پا نگذارید!"}]},{"word":"überhaupt","en":"at all; anyway, in general","ru":"вообще","vi":"tất cả","fa":"اصلا","examples":[{"de":"Ich habe überhaupt keine Zeit.","en":"I have no time at all.","ru":"У меня вообще нет времени.","vi":"Tôi không có thời gian chút nào.","fa":"من اصلا وقت ندارم"},{"de":"Warum machst du das überhaupt?","en":"Why are you doing that anyway?","ru":"Зачем ты вообще это делаешь?","vi":"Tại sao bạn lại làm điều này?","fa":"اصلا چرا این کار را می کنی؟"}]},{"word":"überholen","en":"to overtake, pass","ru":"обгонять","vi":"vượt qua","fa":"سبقت گرفتن","examples":[{"de":"Der Lkw hat uns gefährlich überholt.","en":"The truck overtook us dangerously.","ru":"Грузовик опасно обогнал нас.","vi":"Chiếc xe tải đã vượt qua chúng tôi một cách nguy hiểm.","fa":"کامیون به طرز خطرناکی از ما سبقت گرفت."},{"de":"Man darf hier nicht überholen.","en":"You're not allowed to overtake here.","ru":"Здесь нельзя обгонять.","vi":"Bạn không được phép vượt ở đây.","fa":"اینجا اجازه سبقت گرفتن ندارید."}]},{"word":"überlegen","en":"to think over, consider","ru":"обдумывать, размышлять","vi":"xem xét","fa":"در نظر بگیرید","examples":[{"de":"Ich muss mir das noch überlegen.","en":"I still need to think it over.","ru":"Мне нужно ещё это обдумать.","vi":"Tôi vẫn phải suy nghĩ về nó.","fa":"هنوز باید به آن فکر کنم."},{"de":"Überleg gut, bevor du eine Entscheidung triffst.","en":"Think carefully before you make a decision.","ru":"Хорошо подумай, прежде чем принять решение.","vi":"Hãy suy nghĩ kỹ trước khi đưa ra quyết định.","fa":"قبل از تصمیم گیری خوب فکر کنید."}]},{"word":"übermorgen","en":"the day after tomorrow","ru":"послезавтра","vi":"ngày mốt","fa":"پس فردا","examples":[{"de":"Übermorgen fahre ich nach Berlin.","en":"The day after tomorrow I'm going to Berlin.","ru":"Послезавтра я еду в Берлин.","vi":"Ngày kia tôi sẽ đi Berlin.","fa":"پس فردا به برلین می روم."},{"de":"Wir treffen uns übermorgen um zehn Uhr.","en":"We're meeting the day after tomorrow at ten o'clock.","ru":"Мы встретимся послезавтра в десять часов.","vi":"Chúng ta sẽ gặp nhau vào ngày mốt lúc 10 giờ.","fa":"پس فردا ساعت ده همدیگر را می بینیم."}]},{"word":"übernachten","en":"to stay overnight","ru":"ночевать","vi":"ở lại qua đêm","fa":"شب بمانید","examples":[{"de":"Wir übernachten in einem kleinen Hotel.","en":"We're staying overnight in a small hotel.","ru":"Мы ночуем в маленькой гостинице.","vi":"Chúng tôi nghỉ qua đêm tại một khách sạn nhỏ.","fa":"شب را در یک هتل کوچک می مانیم."},{"de":"Kann ich bei dir übernachten?","en":"Can I stay overnight at your place?","ru":"Могу я переночевать у тебя?","vi":"Tôi có thể ở lại qua đêm với bạn được không?","fa":"آیا می توانم یک شب با شما بمانم؟"}]},{"word":"die Übernachtung","en":"overnight stay","ru":"ночёвка, ночлег","vi":"nghỉ qua đêm","fa":"اقامت یک شبه","examples":[{"de":"Die Übernachtung im Hotel war recht teuer.","en":"The overnight stay in the hotel was quite expensive.","ru":"Ночёвка в отеле была довольно дорогой.","vi":"Việc nghỉ qua đêm ở khách sạn khá tốn kém.","fa":"اقامت یک شبه در هتل بسیار گران بود."},{"de":"Der Preis gilt pro Übernachtung und Person.","en":"The price is per night and per person.","ru":"Цена указана за ночь и за человека.","vi":"Giá mỗi đêm và người.","fa":"قیمت برای هر شب و نفر می باشد."},{"de":"Wir buchen zwei Übernachtungen in Berlin.","en":"We are booking two nights in Berlin.","ru":"Мы бронируем две ночи в Берлине.","vi":"Chúng tôi đặt hai đêm ở Berlin.","fa":"ما دو شب در برلین رزرو می کنیم."}]},{"word":"übernehmen","en":"to take over","ru":"принимать на себя, брать (обязанности)","vi":"tiếp quản","fa":"را بر عهده بگیرد","examples":[{"de":"Sie übernimmt nächstes Jahr die Firma.","en":"She's taking over the company next year.","ru":"Она возьмёт на себя управление компанией в следующем году.","vi":"Cô ấy sẽ tiếp quản công ty vào năm tới.","fa":"او سال آینده این شرکت را برعهده خواهد گرفت."},{"de":"Wer übernimmt die Verantwortung dafür?","en":"Who takes responsibility for that?","ru":"Кто берёт на себя ответственность за это?","vi":"Ai chịu trách nhiệm về việc này?","fa":"چه کسی مسئولیت این کار را بر عهده می گیرد؟"}]},{"word":"überprüfen","en":"to check, verify","ru":"проверять","vi":"kiểm tra","fa":"بررسی کنید","examples":[{"de":"Der Techniker überprüft die Maschine.","en":"The technician checks the machine.","ru":"Техник проверяет машину.","vi":"Kỹ thuật viên kiểm tra máy.","fa":"تکنسین دستگاه را چک می کند."},{"de":"Bitte überprüfen Sie Ihre Angaben noch einmal.","en":"Please check your details once more.","ru":"Пожалуйста, проверьте ещё раз свои данные.","vi":"Vui lòng kiểm tra lại thông tin của bạn.","fa":"لطفا اطلاعات خود را دوباره بررسی کنید."}]},{"word":"überqueren","en":"to cross (a street, etc.)","ru":"переходить, пересекать","vi":"chéo","fa":"متقاطع","examples":[{"de":"Wir überqueren die Straße an der Ampel.","en":"We cross the street at the traffic light.","ru":"Мы переходим улицу на светофоре.","vi":"Chúng tôi băng qua đường ở đèn giao thông.","fa":"از خیابان در چراغ راهنمایی عبور می کنیم."},{"de":"Sei vorsichtig, wenn du die Kreuzung überquerst.","en":"Be careful when you cross the intersection.","ru":"Будь осторожен, переходя перекрёсток.","vi":"Hãy cẩn thận khi băng qua ngã tư.","fa":"هنگام عبور از تقاطع مراقب باشید."}]},{"word":"überraschen","en":"to surprise","ru":"удивлять, делать сюрприз","vi":"ngạc nhiên","fa":"تعجب","examples":[{"de":"Die Nachricht hat mich sehr überrascht.","en":"The news surprised me a lot.","ru":"Эта новость меня очень удивила.","vi":"Tin tức này thực sự làm tôi ngạc nhiên.","fa":"این خبر واقعاً مرا شگفت زده کرد."},{"de":"Wir wollen unsere Oma zum Geburtstag überraschen.","en":"We want to surprise our grandma for her birthday.","ru":"Мы хотим сделать сюрприз бабушке на день рождения.","vi":"Chúng tôi muốn gây bất ngờ cho bà của chúng tôi nhân dịp sinh nhật của bà.","fa":"می خواهیم مادربزرگمان را برای تولدش سورپرایز کنیم."}]},{"word":"überrascht","en":"surprised","ru":"удивлённый","vi":"ngạc nhiên","fa":"متعجب","examples":[{"de":"Er war überrascht, mich dort zu sehen.","en":"He was surprised to see me there.","ru":"Он был удивлён, увидев меня там.","vi":"Anh ấy rất ngạc nhiên khi thấy tôi ở đó.","fa":"او از دیدن من در آنجا تعجب کرد."},{"de":"Ich bin überrascht, wie schnell du das geschafft hast.","en":"I'm surprised how quickly you managed that.","ru":"Я удивлён, как быстро ты с этим справился.","vi":"Tôi ngạc nhiên khi bạn làm điều này nhanh như thế nào.","fa":"تعجب کردم که چقدر سریع این کار را کردی."},{"de":"Alle waren von der guten Nachricht überrascht.","en":"Everyone was surprised by the good news.","ru":"Все были удивлены хорошей новостью.","vi":"Mọi người đều ngạc nhiên trước tin vui.","fa":"همه از این خبر خوب شگفت زده شدند."}]},{"word":"die Überraschung","en":"surprise","ru":"сюрприз, неожиданность","vi":"sự ngạc nhiên","fa":"شگفتی","examples":[{"de":"Was für eine schöne Überraschung!","en":"What a lovely surprise!","ru":"Какой приятный сюрприз!","vi":"Thật là một sự ngạc nhiên đáng yêu!","fa":"چه سورپرایز دوست داشتنی!"},{"de":"Wir haben eine Überraschung für dich vorbereitet.","en":"We have prepared a surprise for you.","ru":"Мы приготовили для тебя сюрприз.","vi":"Chúng tôi đã chuẩn bị một bất ngờ cho bạn.","fa":"برای شما سورپرایز آماده کرده ایم."},{"de":"Zu meiner Überraschung war alles schon erledigt.","en":"To my surprise everything was already done.","ru":"К моему удивлению, всё было уже сделано.","vi":"Trước sự ngạc nhiên của tôi, mọi thứ đã được thực hiện.","fa":"در کمال تعجب، همه چیز از قبل انجام شده بود."}]},{"word":"überreden","en":"to persuade, talk into","ru":"уговаривать","vi":"thuyết phục","fa":"متقاعد کردن","examples":[{"de":"Er hat mich überredet, mitzukommen.","en":"He persuaded me to come along.","ru":"Он уговорил меня пойти с ним.","vi":"Anh ấy đã thuyết phục tôi đi cùng anh ấy.","fa":"او مرا متقاعد کرد که با او بیایم."},{"de":"Lass dich nicht zu etwas überreden, was du nicht willst.","en":"Don't let yourself be talked into something you don't want.","ru":"Не дай себя уговорить на то, чего ты не хочешь.","vi":"Đừng để bản thân bị thuyết phục làm điều gì đó mà bạn không muốn.","fa":"به خودتان اجازه ندهید که برای انجام کاری که نمی خواهید متقاعد شوید."}]},{"word":"die Überschrift","en":"the headline, heading","ru":"заголовок","vi":"tiêu đề","fa":"سرفصل","examples":[{"de":"Lies zuerst die Überschrift des Artikels.","en":"First read the headline of the article.","ru":"Сначала прочитай заголовок статьи.","vi":"Đọc tiêu đề của bài viết đầu tiên.","fa":"ابتدا عنوان مقاله را بخوانید."},{"de":"Die Überschrift ist sehr auffällig.","en":"The heading is very eye-catching.","ru":"Заголовок очень бросается в глаза.","vi":"Tiêu đề rất ấn tượng.","fa":"تیتر بسیار چشمگیر است."}]},{"word":"überschwemmen","en":"to flood, inundate","ru":"затоплять, наводнять","vi":"lũ lụt","fa":"سیل","examples":[{"de":"Der Fluss hat nach dem Regen die Felder überschwemmt.","en":"After the rain the river flooded the fields.","ru":"После дождя река затопила поля.","vi":"Dòng sông tràn ngập cánh đồng sau cơn mưa.","fa":"رودخانه پس از بارندگی مزارع را جاری کرد."},{"de":"Ganze Dörfer wurden vom Hochwasser überschwemmt.","en":"Entire villages were flooded by the high water.","ru":"Целые деревни были затоплены паводком.","vi":"Toàn bộ ngôi làng bị nước lũ nhấn chìm.","fa":"تمام روستاها زیر آب سیل رفتند."},{"de":"Der Markt ist mit billigen Produkten überschwemmt.","en":"The market is flooded with cheap products.","ru":"Рынок наводнён дешёвыми товарами.","vi":"Thị trường tràn ngập sản phẩm giá rẻ.","fa":"بازار پر از محصولات ارزان است."}]},{"word":"die Überschwemmung","en":"flood","ru":"наводнение, затопление","vi":"lũ lụt","fa":"سیل","examples":[{"de":"Nach dem Starkregen kam es zu schweren Überschwemmungen.","en":"After the heavy rain there were severe floods.","ru":"После сильного дождя произошли серьёзные наводнения.","vi":"Sau trận mưa lớn là lũ lụt nghiêm trọng.","fa":"پس از بارش شدید باران جاری شد."},{"de":"Die Überschwemmung setzte den ganzen Keller unter Wasser.","en":"The flood put the whole cellar under water.","ru":"Наводнение затопило весь подвал.","vi":"Nước lũ nhấn chìm toàn bộ tầng hầm.","fa":"سیل تمام زیرزمین را زیر آب برد."},{"de":"Nach der Überschwemmung mussten viele Familien ihre Häuser verlassen.","en":"After the flood many families had to leave their homes.","ru":"После наводнения многим семьям пришлось покинуть свои дома.","vi":"Sau lũ, nhiều gia đình phải rời bỏ nhà cửa.","fa":"پس از وقوع سیل، بسیاری از خانواده ها مجبور به ترک خانه های خود شدند."}]},{"word":"übersetzen","en":"to translate","ru":"переводить","vi":"dịch","fa":"ترجمه کنید","examples":[{"de":"Kannst du diesen Text ins Englische übersetzen?","en":"Can you translate this text into English?","ru":"Можешь перевести этот текст на английский?","vi":"Bạn có thể dịch văn bản này sang tiếng Anh?","fa":"آیا می توانید این متن را به انگلیسی ترجمه کنید؟"},{"de":"Sie übersetzt Bücher aus dem Französischen.","en":"She translates books from French.","ru":"Она переводит книги с французского.","vi":"Cô dịch sách từ tiếng Pháp.","fa":"او کتاب هایی را از فرانسه ترجمه می کند."}]},{"word":"der Übersetzer","en":"translator (male)","ru":"переводчик (муж.)","vi":"người phiên dịch","fa":"مترجم","examples":[{"de":"Er arbeitet als Übersetzer für Englisch und Deutsch.","en":"He works as a translator for English and German.","ru":"Он работает переводчиком с английского и немецкого.","vi":"Anh ấy làm việc như một dịch giả cho tiếng Anh và tiếng Đức.","fa":"او به عنوان مترجم انگلیسی و آلمانی کار می کند."},{"de":"Der Übersetzer hat den Roman ins Deutsche übertragen.","en":"The translator rendered the novel into German.","ru":"Переводчик перевёл роман на немецкий.","vi":"Người dịch đã dịch cuốn tiểu thuyết sang tiếng Đức.","fa":"مترجم این رمان را به آلمانی ترجمه کرده است."},{"de":"Ohne einen guten Übersetzer geht das nicht.","en":"That won't work without a good translator.","ru":"Без хорошего переводчика тут не обойтись.","vi":"Điều này là không thể nếu không có một dịch giả giỏi.","fa":"این کار بدون مترجم خوب امکان پذیر نیست."}]},{"word":"die Übersetzerin","en":"the (female) translator","ru":"переводчица","vi":"người phiên dịch","fa":"مترجم","examples":[{"de":"Meine Schwester arbeitet als Übersetzerin.","en":"My sister works as a translator.","ru":"Моя сестра работает переводчицей.","vi":"Chị tôi làm nghề phiên dịch.","fa":"خواهرم مترجم کار می کند."},{"de":"Die Übersetzerin hat den Roman sehr genau übersetzt.","en":"The translator translated the novel very precisely.","ru":"Переводчица очень точно перевела роман.","vi":"Người dịch đã dịch cuốn tiểu thuyết rất chính xác.","fa":"مترجم این رمان را بسیار دقیق ترجمه کرده است."}]},{"word":"die Übersetzung","en":"translation","ru":"перевод","vi":"bản dịch","fa":"the translation","examples":[{"de":"Die Übersetzung des Buches hat mehrere Monate gedauert.","en":"The translation of the book took several months.","ru":"Перевод книги занял несколько месяцев.","vi":"Việc dịch cuốn sách mất vài tháng.","fa":"ترجمه کتاب چند ماه طول کشید."},{"de":"Ich brauche eine beglaubigte Übersetzung meiner Zeugnisse.","en":"I need a certified translation of my certificates.","ru":"Мне нужен заверенный перевод моих документов об образовании.","vi":"Tôi cần một bản dịch công chứng giấy chứng nhận của tôi.","fa":"من به ترجمه تایید شده گواهینامه هایم نیاز دارم."},{"de":"Diese Übersetzung klingt nicht ganz natürlich.","en":"This translation does not sound entirely natural.","ru":"Этот перевод звучит не совсем естественно.","vi":"Bản dịch này nghe có vẻ không hoàn toàn tự nhiên.","fa":"این ترجمه کاملا طبیعی به نظر نمی رسد."}]},{"word":"die Überstunde","en":"the overtime hour","ru":"сверхурочный час","vi":"làm thêm giờ","fa":"اضافه کاری","examples":[{"de":"Ich musste gestern zwei Überstunden machen.","en":"I had to work two hours of overtime yesterday.","ru":"Вчера мне пришлось отработать два часа сверхурочно.","vi":"Hôm qua tôi phải làm thêm hai giờ.","fa":"دیروز باید دو ساعت اضافه کار می کردم."},{"de":"Werden Überstunden bei euch bezahlt?","en":"Is overtime paid at your company?","ru":"У вас оплачиваются сверхурочные?","vi":"Bạn có trả tiền làm thêm giờ không?","fa":"اضافه کاری پرداخت می کنید؟"}]},{"word":"übertreiben","en":"to exaggerate","ru":"преувеличивать","vi":"phóng đại","fa":"اغراق کردن","examples":[{"de":"Du übertreibst mal wieder!","en":"You're exaggerating again!","ru":"Ты снова преувеличиваешь!","vi":"Bạn lại phóng đại nữa rồi!","fa":"بازم اغراق میکنی!"},{"de":"Er übertreibt gern, wenn er Geschichten erzählt.","en":"He likes to exaggerate when he tells stories.","ru":"Он любит преувеличивать, когда рассказывает истории.","vi":"Anh ấy thích phóng đại khi kể chuyện.","fa":"او دوست دارد وقتی داستان می گوید اغراق کند."}]},{"word":"übertrieben","en":"exaggerated, excessive","ru":"преувеличенный, чрезмерный","vi":"phóng đại","fa":"اغراق آمیز","examples":[{"de":"Seine Reaktion war völlig übertrieben.","en":"His reaction was completely exaggerated.","ru":"Его реакция была совершенно преувеличенной.","vi":"Phản ứng của anh ấy đã hoàn toàn phóng đại.","fa":"واکنش او کاملاً اغراق آمیز بود."},{"de":"Ich finde diese Sorge übertrieben.","en":"I find this worry excessive.","ru":"По-моему, это беспокойство чрезмерно.","vi":"Tôi cho rằng mối lo ngại này đã bị thổi phồng quá mức.","fa":"من فکر می کنم این نگرانی بیش از حد است."},{"de":"Die Preise sind hier übertrieben hoch.","en":"The prices here are excessively high.","ru":"Цены здесь непомерно высокие.","vi":"Giá ở đây cao cắt cổ.","fa":"قیمت ها در اینجا بسیار بالاست."}]},{"word":"überweisen","en":"to transfer (money)","ru":"переводить (деньги)","vi":"chuyển nhượng","fa":"انتقال","examples":[{"de":"Ich habe das Geld schon überwiesen.","en":"I've already transferred the money.","ru":"Я уже перевёл деньги.","vi":"Tôi đã chuyển tiền rồi.","fa":"من قبلاً پول را منتقل کردم."},{"de":"Bitte überweisen Sie die Miete bis zum Ersten.","en":"Please transfer the rent by the first of the month.","ru":"Пожалуйста, переведите арендную плату до первого числа.","vi":"Vui lòng chuyển tiền thuê trước ngày đầu tiên.","fa":"لطفا اجاره را تا روز اول انتقال دهید."}]},{"word":"die Überweisung","en":"bank transfer","ru":"банковский перевод","vi":"việc chuyển giao","fa":"انتقال","examples":[{"de":"Die Miete bezahle ich jeden Monat per Überweisung.","en":"I pay the rent every month by bank transfer.","ru":"Аренду я плачу каждый месяц банковским переводом.","vi":"Tôi trả tiền thuê hàng tháng bằng chuyển khoản ngân hàng.","fa":"من اجاره را هر ماه با حواله بانکی پرداخت می کنم."},{"de":"Die Überweisung dauert meistens einen Werktag.","en":"The transfer usually takes one working day.","ru":"Перевод обычно занимает один рабочий день.","vi":"Việc chuyển tiền thường mất một ngày làm việc.","fa":"انتقال معمولاً یک روز کاری طول می کشد."},{"de":"Bitte machen Sie die Überweisung bis zum Ersten des Monats.","en":"Please make the transfer by the first of the month.","ru":"Пожалуйста, сделайте перевод до первого числа месяца.","vi":"Vui lòng thực hiện chuyển khoản trước ngày đầu tiên của tháng.","fa":"لطفا تا اول ماه انتقال را انجام دهید."}]},{"word":"überwinden","en":"to overcome, to surmount (a difficulty or obstacle)","ru":"преодолевать (трудность, препятствие)","vi":"vượt qua","fa":"غلبه کند","examples":[{"de":"Je mehr Herausforderungen ich überwinde, umso stärker werde ich.","en":"The more challenges I overcome, the stronger I become.","ru":"Чем больше вызовов я преодолеваю, тем сильнее становлюсь.","vi":"Càng vượt qua nhiều thử thách, tôi càng trở nên mạnh mẽ hơn.","fa":"هر چه بیشتر بر چالش ها غلبه کنم، قوی تر می شوم."},{"de":"Mit viel Geduld kann man fast jede Schwierigkeit überwinden.","en":"With a lot of patience you can overcome almost any difficulty.","ru":"С большим терпением можно преодолеть почти любую трудность.","vi":"Với rất nhiều kiên nhẫn, bạn có thể vượt qua hầu hết mọi khó khăn.","fa":"با صبر زیاد می توانید تقریباً بر هر مشکلی غلبه کنید."},{"de":"Sie hat ihre Angst vor dem Fliegen endlich überwunden.","en":"She has finally overcome her fear of flying.","ru":"Она наконец преодолела свой страх перед полётами.","vi":"Cuối cùng cô đã vượt qua được nỗi sợ đi máy bay.","fa":"او سرانجام بر ترس خود از پرواز غلبه کرده است."}]},{"word":"überzeugen","en":"to convince","ru":"убеждать","vi":"thuyết phục","fa":"متقاعد کردن","examples":[{"de":"Mit guten Argumenten konnte er alle überzeugen.","en":"With good arguments he was able to convince everyone.","ru":"Хорошими аргументами он смог убедить всех.","vi":"Anh ấy đã có thể thuyết phục mọi người bằng những lý lẽ thuyết phục.","fa":"او توانست با استدلال های خوبی همه را متقاعد کند."},{"de":"Das Angebot hat mich nicht ganz überzeugt.","en":"The offer didn't fully convince me.","ru":"Предложение не до конца меня убедило.","vi":"Lời đề nghị không hoàn toàn thuyết phục được tôi.","fa":"این پیشنهاد کاملاً من را متقاعد نکرد."}]},{"word":"überzeugend","en":"convincing","ru":"убедительный","vi":"thuyết phục","fa":"متقاعد کننده","examples":[{"de":"Seine Argumente waren sehr überzeugend.","en":"His arguments were very convincing.","ru":"Его аргументы были очень убедительными.","vi":"Những lập luận của ông rất thuyết phục.","fa":"استدلال های او بسیار قانع کننده بود."},{"de":"Die Schauspielerin war in ihrer Rolle überzeugend.","en":"The actress was convincing in her role.","ru":"Актриса была убедительна в своей роли.","vi":"Nữ diễn viên thể hiện rất thuyết phục trong vai diễn của mình.","fa":"این بازیگر در نقش خود قانع کننده بود."}]},{"word":"die Überzeugung","en":"conviction, belief","ru":"убеждение","vi":"sự kết án","fa":"the conviction","examples":[{"de":"Es ist meine feste Überzeugung, dass Bildung wichtig ist.","en":"It is my firm conviction that education is important.","ru":"Я твёрдо убеждён, что образование важно.","vi":"Tôi có niềm tin mãnh liệt rằng giáo dục là quan trọng.","fa":"این اعتقاد قوی من است که آموزش مهم است."},{"de":"Sie vertritt ihre politischen Überzeugungen mit Leidenschaft.","en":"She defends her political beliefs with passion.","ru":"Она страстно отстаивает свои политические убеждения.","vi":"Cô ấy đại diện cho niềm tin chính trị của mình bằng niềm đam mê.","fa":"او عقاید سیاسی خود را با اشتیاق نشان می دهد."},{"de":"Aus Überzeugung kauft er nur regionale Produkte.","en":"Out of conviction he buys only regional products.","ru":"По убеждению он покупает только местные продукты.","vi":"Anh ta chỉ mua các sản phẩm trong khu vực vì bị thuyết phục.","fa":"او فقط از روی اعتقاد به خرید محصولات منطقه ای می پردازد."}]},{"word":"üblich","en":"usual, customary","ru":"обычный, принятый","vi":"thông thường","fa":"معمولی","examples":[{"de":"Das ist hier so üblich.","en":"That's customary here.","ru":"Это здесь принято.","vi":"Đó là điều phổ biến ở đây.","fa":"این در اینجا رایج است."},{"de":"Es ist üblich, sich zur Begrüßung die Hand zu geben.","en":"It's customary to shake hands as a greeting.","ru":"Принято пожимать руку в качестве приветствия.","vi":"Bắt tay như một phong tục là một phong tục.","fa":"رسم بر این است که برای احوالپرسی دست دادن."}]},{"word":"übrig","en":"remaining, left over","ru":"оставшийся","vi":"trái","fa":"سمت چپ","examples":[{"de":"Ist noch Kuchen übrig?","en":"Is there still cake left?","ru":"Ещё остался торт?","vi":"Có còn cái bánh nào không?","fa":"کیک مونده؟"},{"de":"Nach dem Essen war nichts mehr übrig.","en":"After the meal nothing was left.","ru":"После еды ничего не осталось.","vi":"Ăn xong chẳng còn gì nữa.","fa":"بعد از غذا چیزی نمانده بود."}]},{"word":"übrigens","en":"by the way","ru":"кстати","vi":"Nhân tiện","fa":"به هر حال","examples":[{"de":"Übrigens, hast du meine E-Mail bekommen?","en":"By the way, did you get my email?","ru":"Кстати, ты получил моё письмо?","vi":"Nhân tiện, bạn có nhận được email của tôi không?","fa":"راستی ایمیل من رو گرفتی؟"},{"de":"Das Restaurant ist übrigens sehr gut.","en":"By the way, the restaurant is very good.","ru":"Кстати, ресторан очень хороший.","vi":"Nhân tiện, nhà hàng rất ngon.","fa":"اتفاقا رستوران خیلی خوبیه."}]},{"word":"die Übungsstunde","en":"practice session, class","ru":"тренировочное занятие, урок","vi":"buổi thực hành","fa":"جلسه تمرین","examples":[{"de":"Die Übungsstunde dauert etwa neunzig Minuten.","en":"The class lasts about ninety minutes.","ru":"Занятие длится примерно девяносто минут.","vi":"Buổi thực hành kéo dài khoảng chín mươi phút.","fa":"جلسه تمرین تقریباً نود دقیقه طول می کشد."},{"de":"Jede Übungsstunde beginnt mit ruhigem Atmen.","en":"Every class begins with calm breathing.","ru":"Каждое занятие начинается со спокойного дыхания.","vi":"Mỗi buổi tập bắt đầu bằng hơi thở bình tĩnh.","fa":"هر جلسه تمرین با تنفس آرام آغاز می شود."},{"de":"Ich freue mich auf die nächste Übungsstunde.","en":"I'm looking forward to the next class.","ru":"Я жду следующего занятия.","vi":"Tôi rất mong chờ buổi tập tiếp theo.","fa":"من مشتاقانه منتظر جلسه تمرین بعدی هستم."}]},{"word":"das Ufer","en":"the (river/lake) bank, shore","ru":"берег","vi":"bờ biển","fa":"ساحل","examples":[{"de":"Wir sind am Ufer des Sees spazieren gegangen.","en":"We went for a walk along the shore of the lake.","ru":"Мы гуляли по берегу озера.","vi":"Chúng tôi đi dạo trên bờ hồ.","fa":"رفتیم کنار دریاچه قدم زدیم."},{"de":"Das Boot liegt am Ufer.","en":"The boat lies on the shore.","ru":"Лодка стоит на берегу.","vi":"Thuyền đang ở trên bờ.","fa":"قایق در ساحل است."}]},{"word":"die Uhr","en":"the clock, watch; o'clock","ru":"часы; час (при указании времени)","vi":"đồng hồ","fa":"ساعت","examples":[{"de":"Meine Uhr geht falsch.","en":"My watch is wrong.","ru":"Мои часы идут неправильно.","vi":"Đồng hồ của tôi sai rồi.","fa":"ساعت من اشتباه است"},{"de":"Es ist jetzt acht Uhr.","en":"It is eight o'clock now.","ru":"Сейчас восемь часов.","vi":"Bây giờ là tám giờ.","fa":"الان ساعت هشت است."}]},{"word":"um","en":"around; at (time)","ru":"вокруг; в (при времени)","vi":"xung quanh","fa":"اطراف","examples":[{"de":"Das Fest beginnt um acht Uhr.","en":"The party starts at eight o'clock.","ru":"Праздник начинается в восемь часов.","vi":"Lễ hội bắt đầu lúc tám giờ.","fa":"این جشنواره از ساعت هشت آغاز می شود."},{"de":"Wir sitzen um den Tisch herum.","en":"We are sitting around the table.","ru":"Мы сидим вокруг стола.","vi":"Chúng tôi ngồi quanh bàn.","fa":"دور میز می نشینیم."}]},{"word":"um … zu","en":"in order to","ru":"чтобы (с инфинитивом)","vi":"đến…đến","fa":"به… به","examples":[{"de":"Ich lerne Deutsch, um in Deutschland zu studieren.","en":"I'm learning German in order to study in Germany.","ru":"Я учу немецкий, чтобы учиться в Германии.","vi":"Tôi đang học tiếng Đức để du học ở Đức.","fa":"در حال یادگیری زبان آلمانی برای تحصیل در آلمان هستم."},{"de":"Er steht früh auf, um pünktlich zur Arbeit zu kommen.","en":"He gets up early in order to arrive at work on time.","ru":"Он встаёт рано, чтобы вовремя прийти на работу.","vi":"Anh ấy dậy sớm để đi làm đúng giờ.","fa":"او زود بیدار می شود تا به موقع به محل کارش برسد."}]},{"word":"um den heißen Brei herumreden","en":"to beat around the bush","ru":"ходить вокруг да около","vi":"để đánh xung quanh bụi rậm","fa":"به دور بوته زدن","examples":[{"de":"Red nicht um den heißen Brei herum, sag es direkt!","en":"Don't beat around the bush, just say it!","ru":"Не ходи вокруг да около, скажи прямо!","vi":"Đừng vòng vo nữa, hãy nói thẳng đi!","fa":"دور بوش نزن، فوراً بگو!"}]},{"word":"umarmen","en":"to hug, embrace","ru":"обнимать","vi":"ôm","fa":"بغل کردن","examples":[{"de":"Sie umarmte ihn zur Begrüßung.","en":"She hugged him as a greeting.","ru":"Она обняла его в знак приветствия.","vi":"Cô ôm anh chào hỏi.","fa":"به نشانه سلام او را در آغوش گرفت."},{"de":"Die Kinder umarmten ihre Mutter.","en":"The children hugged their mother.","ru":"Дети обняли свою маму.","vi":"Những đứa trẻ ôm chặt lấy mẹ.","fa":"بچه ها مادرشان را در آغوش گرفتند."}]},{"word":"umdrehen","en":"to turn around, to turn over","ru":"поворачиваться, переворачивать","vi":"quay lại","fa":"برگرد","examples":[{"de":"Bitte dreh dich nicht um.","en":"Please don't turn around.","ru":"Пожалуйста, не оборачивайся.","vi":"Xin đừng quay lại.","fa":"لطفا برنگردید"},{"de":"Sie drehte den Schlüssel im Schloss um.","en":"She turned the key in the lock.","ru":"Она повернула ключ в замке.","vi":"Cô vặn chìa khóa vào ổ.","fa":"کلید را در قفل چرخاند."},{"de":"Wir müssen das Steak umdrehen, sonst verbrennt es.","en":"We have to turn the steak over, otherwise it'll burn.","ru":"Нужно перевернуть стейк, иначе он пригорит.","vi":"Chúng ta phải lật miếng bít tết nếu không nó sẽ bị cháy.","fa":"باید استیک را برگردانیم وگرنه می سوزد."}]},{"word":"der Umfang","en":"perimeter, circumference","ru":"периметр, длина окружности","vi":"phạm vi","fa":"دامنه","examples":[{"de":"Der Umfang eines Quadrats ist die Summe aller vier Seiten.","en":"The perimeter of a square is the sum of all four sides.","ru":"Периметр квадрата — это сумма всех четырёх сторон.","vi":"Chu vi của hình vuông là tổng của bốn cạnh.","fa":"محیط یک مربع مجموع هر چهار ضلع است."},{"de":"Wir berechneten den Umfang des Kreises mit Pi.","en":"We calculated the circumference of the circle using pi.","ru":"Мы вычислили длину окружности через число пи.","vi":"Chúng tôi đã tính chu vi của vòng tròn bằng Pi.","fa":"محیط دایره را با استفاده از Pi محاسبه کردیم."},{"de":"Der Umfang des Spielfelds beträgt zweihundert Meter.","en":"The perimeter of the pitch is two hundred metres.","ru":"Периметр поля составляет двести метров.","vi":"Chu vi của sân chơi là hai trăm mét.","fa":"محیط زمین بازی دویست متر است."}]},{"word":"die Umfrage","en":"the survey, poll","ru":"опрос","vi":"cuộc khảo sát","fa":"نظرسنجی","examples":[{"de":"Wir haben eine Umfrage unter den Studenten gemacht.","en":"We conducted a survey among the students.","ru":"Мы провели опрос среди студентов.","vi":"Chúng tôi đã tiến hành một cuộc khảo sát giữa các sinh viên.","fa":"ما یک نظرسنجی بین دانش آموزان انجام دادیم."},{"de":"Laut der Umfrage sind die meisten zufrieden.","en":"According to the survey, most people are satisfied.","ru":"Согласно опросу, большинство довольны.","vi":"Theo khảo sát, hầu hết đều hài lòng.","fa":"بر اساس نظرسنجی، اکثر آنها راضی هستند."}]},{"word":"der Umgang","en":"dealings, handling, contact","ru":"обращение, обхождение, контакт","vi":"việc xử lý","fa":"رسیدگی","examples":[{"de":"Der Umgang mit Kindern erfordert viel Geduld.","en":"Dealing with children requires a lot of patience.","ru":"Обращение с детьми требует большого терпения.","vi":"Đối xử với trẻ em đòi hỏi rất nhiều kiên nhẫn.","fa":"برخورد با کودکان نیاز به صبر و حوصله زیادی دارد."},{"de":"Sie hat einen freundlichen Umgang mit ihren Kollegen.","en":"She has a friendly way of dealing with her colleagues.","ru":"У неё приветливая манера общения с коллегами.","vi":"Cô ấy có mối quan hệ thân thiện với đồng nghiệp.","fa":"او رابطه دوستانه ای با همکارانش دارد."},{"de":"Der Umgang mit dem neuen Programm fällt mir noch schwer.","en":"Handling the new software is still difficult for me.","ru":"Обращение с новым ПО пока даётся мне с трудом.","vi":"Tôi vẫn cảm thấy khó khăn khi sử dụng chương trình mới.","fa":"من هنوز استفاده از برنامه جدید را دشوار می دانم."}]},{"word":"die Umgebung","en":"the surroundings, area","ru":"окрестности, окружение","vi":"môi trường xung quanh","fa":"محیط اطراف","examples":[{"de":"Die Umgebung des Schlosses ist sehr schön.","en":"The surroundings of the castle are very beautiful.","ru":"Окрестности замка очень красивы.","vi":"Khung cảnh xung quanh lâu đài rất đẹp.","fa":"محیط اطراف قلعه بسیار زیباست."},{"de":"Wir haben die Umgebung der Stadt erkundet.","en":"We explored the surrounding area of the city.","ru":"Мы исследовали окрестности города.","vi":"Chúng tôi khám phá khu vực xung quanh thành phố.","fa":"اطراف شهر را گشتیم."}]},{"word":"umgehen","en":"to handle, deal with","ru":"обращаться (с кем-л./чем-л.)","vi":"đối phó với","fa":"با","examples":[{"de":"Er kann gut mit Kindern umgehen.","en":"He can handle children well.","ru":"Он умеет хорошо ладить с детьми.","vi":"Anh ấy tốt với trẻ em.","fa":"او با بچه ها خوب است."},{"de":"Wie gehst du mit Stress um?","en":"How do you deal with stress?","ru":"Как ты справляешься со стрессом?","vi":"Làm thế nào để bạn đối phó với căng thẳng?","fa":"چگونه با استرس مقابله می کنید؟"}]},{"word":"umgekehrt","en":"the other way around, vice versa","ru":"наоборот","vi":"ngược lại","fa":"برعکس","examples":[{"de":"Es war genau umgekehrt, als du denkst.","en":"It was exactly the opposite of what you think.","ru":"Всё было как раз наоборот, чем ты думаешь.","vi":"Nó hoàn toàn trái ngược với những gì bạn nghĩ.","fa":"دقیقا برعکس چیزی بود که شما فکر می کنید."},{"de":"Normalerweise mache ich es umgekehrt.","en":"Usually I do it the other way around.","ru":"Обычно я делаю наоборот.","vi":"Tôi thường làm theo cách khác.","fa":"من معمولا این کار را برعکس انجام می دهم."}]},{"word":"die Umleitung","en":"the detour, diversion","ru":"объезд","vi":"sự chuyển hướng","fa":"تغییر مسیر","examples":[{"de":"Wegen der Bauarbeiten gibt es eine Umleitung.","en":"There's a detour because of the construction work.","ru":"Из-за строительных работ есть объезд.","vi":"Có đường vòng do công trình xây dựng.","fa":"انحراف به دلیل کار ساختمانی وجود دارد."},{"de":"Wir mussten der Umleitung folgen.","en":"We had to follow the detour.","ru":"Нам пришлось следовать объезду.","vi":"Chúng tôi phải đi theo đường vòng.","fa":"باید مسیر انحرافی را دنبال می کردیم."}]},{"word":"der Umsatz","en":"turnover, revenue","ru":"оборот, выручка","vi":"việc bán hàng","fa":"فروش","examples":[{"de":"Der Umsatz der Firma ist im letzten Jahr gestiegen.","en":"The company's turnover rose last year.","ru":"В прошлом году оборот фирмы вырос.","vi":"Doanh số bán hàng của công ty đã tăng vào năm ngoái.","fa":"فروش این شرکت در سال گذشته افزایش یافته است."},{"de":"Im Sommer machen wir den meisten Umsatz.","en":"We make the most revenue in summer.","ru":"Больше всего выручки мы получаем летом.","vi":"Chúng tôi bán được nhiều hàng nhất vào mùa hè.","fa":"ما بیشترین فروش را در تابستان داریم."},{"de":"Ein höherer Umsatz bedeutet nicht automatisch mehr Gewinn.","en":"A higher turnover doesn't automatically mean more profit.","ru":"Более высокий оборот автоматически не означает большей прибыли.","vi":"Doanh số bán hàng cao hơn không tự động có nghĩa là lợi nhuận nhiều hơn.","fa":"فروش بالاتر به طور خودکار به معنای سود بیشتر نیست."}]},{"word":"umso","en":"all the more (the ... the more)","ru":"тем (более)","vi":"hơn thế nữa","fa":"هر چه بیشتر","examples":[{"de":"Je später es wird, umso müder werde ich.","en":"The later it gets, the more tired I become.","ru":"Чем позже становится, тем более уставшим я становлюсь.","vi":"Càng về sau tôi càng mệt mỏi.","fa":"هر چه دیرتر می شود، بیشتر خسته می شوم."},{"de":"Umso besser, wenn du auch kommst!","en":"All the better if you come too!","ru":"Тем лучше, если ты тоже придёшь!","vi":"Sẽ tốt hơn nếu bạn cũng đến!","fa":"اگر شما هم بیای خیلی بهتر!"}]},{"word":"umsonst","en":"for free; in vain","ru":"бесплатно; напрасно","vi":"miễn phí","fa":"به صورت رایگان","examples":[{"de":"Der Eintritt ist heute umsonst.","en":"Admission is free today.","ru":"Сегодня вход бесплатный.","vi":"Vào cửa miễn phí ngày hôm nay.","fa":"ورود امروز رایگان است"},{"de":"Alle Mühe war umsonst.","en":"All the effort was in vain.","ru":"Все усилия были напрасны.","vi":"Mọi nỗ lực đều vô ích.","fa":"تمام تلاش ها بیهوده بود."}]},{"word":"umsteigen","en":"to change (trains/buses), transfer","ru":"делать пересадку","vi":"chuyển đổi","fa":"سوئیچ","examples":[{"de":"In München müssen wir umsteigen.","en":"We have to change trains in Munich.","ru":"В Мюнхене нам нужно сделать пересадку.","vi":"Chúng ta phải đổi tàu ở Munich.","fa":"باید در مونیخ قطار عوض کنیم."},{"de":"Steigen wir hier in die U-Bahn um?","en":"Do we transfer to the subway here?","ru":"Мы здесь пересаживаемся на метро?","vi":"Chúng ta có nên đổi sang tàu điện ngầm ở đây không?","fa":"آیا باید اینجا را به مترو تغییر دهیم؟"}]},{"word":"umstritten","en":"controversial; disputed","ru":"спорный","vi":"gây tranh cãi","fa":"بحث برانگیز","examples":[{"de":"Das neue Gesetz ist sehr umstritten.","en":"The new law is very controversial.","ru":"Новый закон весьма спорный.","vi":"Luật mới đang gây nhiều tranh cãi.","fa":"قانون جدید بسیار بحث برانگیز است."},{"de":"Ob die Methode wirkt, ist unter Experten umstritten.","en":"Whether the method works is disputed among experts.","ru":"Работает ли этот метод, среди экспертов спорно.","vi":"Liệu phương pháp này có hiệu quả hay không vẫn còn gây tranh cãi giữa các chuyên gia.","fa":"اینکه آیا این روش کار می کند یا خیر، در میان کارشناسان بحث برانگیز است."}]},{"word":"umstürzen","en":"to topple, to overturn; to overthrow","ru":"опрокидывать, валить; свергать","vi":"lật đổ","fa":"واژگون شدن","examples":[{"de":"Der Sturm hat viele Bäume umgestürzt.","en":"The storm toppled many trees.","ru":"Буря повалила много деревьев.","vi":"Cơn bão đã quật ngã nhiều cây cối.","fa":"طوفان درختان زیادی را فرو ریخت."},{"de":"Pass auf, dass die Leiter nicht umstürzt!","en":"Be careful that the ladder doesn't fall over!","ru":"Осторожно, чтобы лестница не упала!","vi":"Hãy cẩn thận kẻo thang bị đổ!","fa":"مواظب باشید نردبان سقوط نکند!"},{"de":"Das Volk wollte die Regierung umstürzen.","en":"The people wanted to overthrow the government.","ru":"Народ хотел свергнуть правительство.","vi":"Người dân muốn lật đổ chính quyền.","fa":"مردم می خواستند حکومت را سرنگون کنند."}]},{"word":"der Umtausch","en":"exchange (of goods)","ru":"обмен (товара)","vi":"sự trao đổi","fa":"مبادله","examples":[{"de":"Der Umtausch ist nur mit Kassenbon möglich.","en":"An exchange is only possible with a receipt.","ru":"Обмен возможен только при наличии чека.","vi":"Việc trao đổi chỉ có thể được thực hiện khi có biên nhận.","fa":"تعویض فقط با قبض امکان پذیر است."},{"de":"Beim Umtausch der Schuhe gab es keine Probleme.","en":"There were no problems with the exchange of the shoes.","ru":"С обменом обуви не было никаких проблем.","vi":"Không có vấn đề gì khi đổi giày.","fa":"هیچ مشکلی برای تعویض کفش وجود نداشت."},{"de":"Reduzierte Ware ist vom Umtausch ausgeschlossen.","en":"Reduced goods are excluded from exchange.","ru":"Уценённый товар обмену не подлежит.","vi":"Hàng giảm giá không được đổi trả.","fa":"کالاهای کاهش یافته قابل تعویض نیستند."}]},{"word":"umtauschen","en":"to exchange (goods)","ru":"обменивать (товар)","vi":"trao đổi","fa":"مبادله","examples":[{"de":"Ich möchte dieses Hemd umtauschen.","en":"I would like to exchange this shirt.","ru":"Я хотел бы обменять эту рубашку.","vi":"Tôi muốn đổi chiếc áo này.","fa":"من می خواهم این پیراهن را عوض کنم."},{"de":"Kann man das Geschenk umtauschen?","en":"Can the gift be exchanged?","ru":"Можно обменять этот подарок?","vi":"Quà tặng có thể đổi được không?","fa":"آیا هدیه قابل تعویض است؟"}]},{"word":"die Umwelt","en":"the environment","ru":"окружающая среда","vi":"môi trường","fa":"محیط زیست","examples":[{"de":"Wir müssen die Umwelt besser schützen.","en":"We need to protect the environment better.","ru":"Нам нужно лучше защищать окружающую среду.","vi":"Chúng ta phải bảo vệ môi trường tốt hơn.","fa":"ما باید از محیط زیست بهتر محافظت کنیم."},{"de":"Plastik schadet der Umwelt.","en":"Plastic harms the environment.","ru":"Пластик вредит окружающей среде.","vi":"Nhựa gây hại cho môi trường.","fa":"پلاستیک به محیط زیست آسیب می رساند."}]},{"word":"umweltbewusst","en":"environmentally conscious","ru":"экологически сознательный","vi":"có ý thức về môi trường","fa":"آگاه به محیط زیست","examples":[{"de":"Sie kauft umweltbewusst im regionalen Laden ein.","en":"She shops in an environmentally conscious way at the local store.","ru":"Она экологически сознательно делает покупки в местном магазине.","vi":"Cô mua sắm có ý thức bảo vệ môi trường tại các cửa hàng địa phương.","fa":"او با آگاهی از محیط زیست در فروشگاه های محلی خرید می کند."},{"de":"Eine umweltbewusste Familie trennt ihren Müll.","en":"An environmentally conscious family separates its rubbish.","ru":"Экологически сознательная семья сортирует свой мусор.","vi":"Một gia đình có ý thức bảo vệ môi trường sẽ phân loại rác thải của mình.","fa":"خانواده ای آگاه به محیط زیست زباله های خود را جدا می کنند."},{"de":"Viele junge Menschen leben heute umweltbewusst.","en":"Many young people today live in an environmentally conscious way.","ru":"Многие молодые люди сегодня живут экологически сознательно.","vi":"Nhiều người trẻ ngày nay có lối sống có ý thức về môi trường.","fa":"امروزه بسیاری از جوانان سبک زندگی آگاهانه ای از محیط زیست دارند."}]},{"word":"umweltfreundlich","en":"environmentally friendly","ru":"экологичный; экологически чистый","vi":"thân thiện với môi trường","fa":"سازگار با محیط زیست","examples":[{"de":"Mit dem Fahrrad zu fahren ist umweltfreundlich.","en":"Riding a bike is environmentally friendly.","ru":"Ездить на велосипеде экологично.","vi":"Đi xe đạp là thân thiện với môi trường.","fa":"دوچرخه سواری دوستدار محیط زیست است."},{"de":"Wir kaufen möglichst umweltfreundliche Produkte.","en":"We buy environmentally friendly products where possible.","ru":"Мы по возможности покупаем экологичные товары.","vi":"Chúng tôi mua những sản phẩm thân thiện với môi trường nhất có thể.","fa":"ما محصولاتی را خریداری می کنیم که تا حد امکان سازگار با محیط زیست باشند."}]},{"word":"umweltschädlich","en":"harmful to the environment","ru":"вредный для окружающей среды","vi":"có hại cho môi trường","fa":"برای محیط زیست مضر است","examples":[{"de":"Viele alte Autos sind sehr umweltschädlich.","en":"Many old cars are very harmful to the environment.","ru":"Многие старые машины очень вредны для окружающей среды.","vi":"Nhiều xe cũ rất có hại cho môi trường.","fa":"بسیاری از خودروهای قدیمی برای محیط زیست بسیار مضر هستند."},{"de":"Plastiktüten gelten als besonders umweltschädlich.","en":"Plastic bags are considered especially harmful to the environment.","ru":"Пластиковые пакеты считаются особенно вредными для окружающей среды.","vi":"Túi nhựa được coi là đặc biệt có hại cho môi trường.","fa":"کیسه های پلاستیکی به ویژه برای محیط زیست مضر در نظر گرفته می شوند."},{"de":"Die Firma musste eine umweltschädliche Methode aufgeben.","en":"The company had to give up a method harmful to the environment.","ru":"Фирме пришлось отказаться от вредного для окружающей среды метода.","vi":"Công ty đã phải từ bỏ một phương pháp có hại cho môi trường.","fa":"این شرکت مجبور شد روش مضر برای محیط زیست را کنار بگذارد."}]},{"word":"der Umweltschutz","en":"environmental protection","ru":"охрана окружающей среды","vi":"bảo vệ môi trường","fa":"حفاظت از محیط زیست","examples":[{"de":"Umweltschutz beginnt schon im eigenen Haushalt.","en":"Environmental protection begins in your own household.","ru":"Охрана окружающей среды начинается уже в собственном доме.","vi":"Bảo vệ môi trường bắt đầu từ chính ngôi nhà của bạn.","fa":"حفاظت از محیط زیست از خانه شما آغاز می شود."},{"de":"Die Regierung investiert mehr Geld in den Umweltschutz.","en":"The government is investing more money in environmental protection.","ru":"Правительство вкладывает больше денег в охрану окружающей среды.","vi":"Chính phủ đang đầu tư nhiều tiền hơn vào việc bảo vệ môi trường.","fa":"دولت پول بیشتری برای حفاظت از محیط زیست سرمایه گذاری می کند."}]},{"word":"der Umweltschützer","en":"environmentalist","ru":"защитник окружающей среды, эколог","vi":"nhà bảo vệ môi trường","fa":"محیط بان","examples":[{"de":"Der Umweltschützer sammelt Müll am Flussufer.","en":"The environmentalist collects rubbish along the riverbank.","ru":"Защитник окружающей среды собирает мусор на берегу реки.","vi":"Nhà bảo vệ môi trường thu gom rác trên bờ sông.","fa":"محیط بان زباله ها را در حاشیه رودخانه جمع آوری می کند."},{"de":"Umweltschützer warnen vor dem Verlust der Wälder.","en":"Environmentalists warn against the loss of forests.","ru":"Защитники окружающей среды предупреждают об исчезновении лесов.","vi":"Các nhà môi trường cảnh báo về việc mất rừng.","fa":"کارشناسان محیط زیست نسبت به از بین رفتن جنگل ها هشدار می دهند."},{"de":"Sie ist eine bekannte Umweltschützerin in unserer Stadt.","en":"She is a well-known environmentalist in our town.","ru":"Она известная защитница окружающей среды в нашем городе.","vi":"Cô ấy là một nhà bảo vệ môi trường nổi tiếng ở thành phố của chúng tôi.","fa":"او یک دوستدار محیط زیست شناخته شده در شهر ماست."}]},{"word":"die Umweltverschmutzung","en":"environmental pollution","ru":"загрязнение окружающей среды","vi":"ô nhiễm môi trường","fa":"آلودگی محیط زیست","examples":[{"de":"Die Umweltverschmutzung in den Großstädten nimmt jedes Jahr zu.","en":"Environmental pollution in the big cities increases every year.","ru":"Загрязнение окружающей среды в крупных городах растёт каждый год.","vi":"Ô nhiễm ở các thành phố lớn đang gia tăng hàng năm.","fa":"آلودگی در شهرهای بزرگ هر سال در حال افزایش است."},{"de":"Plastik im Meer ist ein großes Problem der Umweltverschmutzung.","en":"Plastic in the sea is a major problem of environmental pollution.","ru":"Пластик в море — большая проблема загрязнения окружающей среды.","vi":"Nhựa trong đại dương là một vấn đề ô nhiễm lớn.","fa":"پلاستیک در اقیانوس یک مشکل عمده آلودگی است."},{"de":"Viele Krankheiten hängen mit der Umweltverschmutzung zusammen.","en":"Many illnesses are connected with environmental pollution.","ru":"Многие болезни связаны с загрязнением окружающей среды.","vi":"Nhiều bệnh tật có liên quan đến ô nhiễm môi trường.","fa":"بسیاری از بیماری ها با آلودگی محیط زیست مرتبط هستند."}]},{"word":"umziehen","en":"to move (house)","ru":"переезжать (менять место жительства)","vi":"di chuyển","fa":"حرکت کنید","examples":[{"de":"Wir ziehen nächsten Monat um.","en":"We're moving next month.","ru":"Мы переезжаем в следующем месяце.","vi":"Chúng tôi sẽ chuyển đi vào tháng tới.","fa":"ماه آینده حرکت می کنیم."},{"de":"Sie sind in eine größere Wohnung umgezogen.","en":"They moved into a bigger apartment.","ru":"Они переехали в квартиру побольше.","vi":"Họ chuyển đến một căn hộ lớn hơn.","fa":"آنها به یک آپارتمان بزرگتر نقل مکان کردند."}]},{"word":"der Umzug","en":"move (relocation), parade","ru":"переезд (смена жилья); шествие, парад","vi":"di chuyển","fa":"حرکت","examples":[{"de":"Der Umzug in die neue Wohnung war anstrengend.","en":"The move to the new flat was exhausting.","ru":"Переезд в новую квартиру был утомительным.","vi":"Việc chuyển đến căn hộ mới thật căng thẳng.","fa":"نقل مکان به آپارتمان جدید استرس زا بود."},{"de":"Beim Umzug halfen uns viele Freunde.","en":"Many friends helped us with the move.","ru":"С переездом нам помогали многие друзья.","vi":"Nhiều người bạn đã giúp chúng tôi di chuyển.","fa":"دوستان زیادی در این جابجایی به ما کمک کردند."},{"de":"Nach dem Umzug fühlten wir uns schnell zu Hause.","en":"After the move we quickly felt at home.","ru":"После переезда мы быстро почувствовали себя как дома.","vi":"Sau khi chuyển đi, chúng tôi nhanh chóng cảm thấy như ở nhà.","fa":"بعد از حرکت به سرعت احساس کردیم که در خانه هستیم."}]},{"word":"un-","en":"un- (negating prefix, e.g. ungesund = unhealthy)","ru":"не- (отрицательная приставка, напр. ungesund — нездоровый)","vi":"bỏ-","fa":"غیر","examples":[{"de":"Die Vorsilbe „un-“ macht aus „glücklich“ das Gegenteil „unglücklich“.","en":"The prefix \"un-\" turns \"glücklich\" into its opposite \"unglücklich\".","ru":"Приставка «un-» превращает «glücklich» в противоположное «unglücklich».","vi":"Tiền tố “un-” biến “hạnh phúc” thành từ trái nghĩa là “không hạnh phúc”.","fa":"پیشوند \"un-\" \"خوشحال\" را به مقابل \"ناشاد\" تبدیل می کند."},{"de":"Viele deutsche Adjektive werden mit „un-“ verneint.","en":"Many German adjectives are negated with \"un-\".","ru":"Многие немецкие прилагательные отрицаются с помощью «un-».","vi":"Nhiều tính từ tiếng Đức bị phủ định bằng “un-”.","fa":"بسیاری از صفت های آلمانی با \"un-\" نفی می شوند."},{"de":"„Unbekannt“ heißt einfach „nicht bekannt“.","en":"\"Unbekannt\" simply means \"not known\".","ru":"«Unbekannt» просто означает «неизвестный».","vi":"“Không biết” đơn giản có nghĩa là “không biết”.","fa":"\"ناشناخته\" به سادگی به معنای \"ناشناخته\" است."}]},{"word":"die Unabhängigkeit","en":"independence","ru":"независимость","vi":"sự độc lập","fa":"the independence","examples":[{"de":"Das Volk kämpfte jahrelang für seine Unabhängigkeit.","en":"The people fought for years for their independence.","ru":"Народ годами боролся за свою независимость.","vi":"Người dân đã đấu tranh giành độc lập trong nhiều năm.","fa":"مردم سال ها برای استقلال خود جنگیدند."},{"de":"Die Unabhängigkeit wurde 1947 ausgerufen.","en":"Independence was declared in 1947.","ru":"Независимость была провозглашена в 1947 году.","vi":"Độc lập được tuyên bố vào năm 1947.","fa":"استقلال در سال 1947 اعلام شد."},{"de":"Nach der Unabhängigkeit gab es eine neue Verfassung.","en":"After independence there was a new constitution.","ru":"После обретения независимости появилась новая конституция.","vi":"Sau khi độc lập có hiến pháp mới.","fa":"پس از استقلال قانون اساسی جدید وجود داشت."}]},{"word":"unbedingt","en":"absolutely, definitely","ru":"обязательно, непременно","vi":"tuyệt đối","fa":"مطلقا","examples":[{"de":"Du musst diesen Film unbedingt sehen.","en":"You absolutely must see this film.","ru":"Тебе обязательно нужно посмотреть этот фильм.","vi":"Bạn nhất định phải xem bộ phim này.","fa":"این فیلم را حتما ببینید"},{"de":"Ich möchte unbedingt nach Japan reisen.","en":"I definitely want to travel to Japan.","ru":"Я непременно хочу поехать в Японию.","vi":"Tôi thực sự muốn đi du lịch đến Nhật Bản.","fa":"من واقعاً می خواهم به ژاپن سفر کنم."}]},{"word":"unbekannt","en":"unknown","ru":"неизвестный","vi":"không rõ","fa":"ناشناخته","examples":[{"de":"Der Täter ist bisher unbekannt.","en":"The culprit is unknown so far.","ru":"Виновник пока неизвестен.","vi":"Thủ phạm vẫn chưa được xác định.","fa":"عامل جنایت هنوز مشخص نیست."},{"de":"Der Künstler war zu Lebzeiten völlig unbekannt.","en":"The artist was completely unknown during his lifetime.","ru":"При жизни художник был совершенно неизвестен.","vi":"Người nghệ sĩ hoàn toàn không được biết đến trong suốt cuộc đời của mình.","fa":"این هنرمند در طول زندگی خود کاملاً ناشناخته بود."},{"de":"Die Ursache des Brandes ist noch unbekannt.","en":"The cause of the fire is still unknown.","ru":"Причина пожара до сих пор неизвестна.","vi":"Hiện vẫn chưa rõ nguyên nhân vụ cháy.","fa":"علت آتش سوزی هنوز مشخص نیست."}]},{"word":"und","en":"and","ru":"и","vi":"và","fa":"و","examples":[{"de":"Ich kaufe Brot und Milch.","en":"I'm buying bread and milk.","ru":"Я покупаю хлеб и молоко.","vi":"Tôi mua bánh mì và sữa.","fa":"نان و شیر می خرم."},{"de":"Sie ist klug und freundlich.","en":"She is smart and friendly.","ru":"Она умная и дружелюбная.","vi":"Cô ấy thông minh và tốt bụng.","fa":"او باهوش و مهربان است."}]},{"word":"unentschieden","en":"undecided; (sport) drawn, a draw","ru":"нерешённый; (спорт) ничья, вничью","vi":"chưa quyết định","fa":"بلاتکلیف","examples":[{"de":"Das Spiel endete unentschieden, eins zu eins.","en":"The match ended in a draw, one to one.","ru":"Матч закончился вничью, один к одному.","vi":"Trận đấu kết thúc với tỷ số hòa, một chọi một.","fa":"این بازی با تساوی یک بر یک به پایان رسید."},{"de":"Ich bin noch unentschieden, ob ich mitkomme.","en":"I'm still undecided about whether I'll come along.","ru":"Я ещё не решил, пойду ли я с вами.","vi":"Tôi vẫn chưa quyết định liệu tôi có đến hay không.","fa":"من هنوز تصمیم ندارم بیام یا نه."},{"de":"Nach dem Unentschieden waren beide Mannschaften zufrieden.","en":"After the draw both teams were satisfied.","ru":"После ничьей обе команды были довольны.","vi":"Cả hai đội đều hài lòng sau trận hòa.","fa":"هر دو تیم پس از تساوی راضی بودند."}]},{"word":"der Unfall","en":"the accident","ru":"авария, несчастный случай","vi":"vụ tai nạn","fa":"تصادف","examples":[{"de":"Gestern gab es einen Unfall auf der Autobahn.","en":"Yesterday there was an accident on the highway.","ru":"Вчера на автомагистрали произошла авария.","vi":"Hôm qua có một vụ tai nạn trên đường cao tốc.","fa":"دیروز تصادفی در بزرگراه رخ داد."},{"de":"Zum Glück wurde bei dem Unfall niemand verletzt.","en":"Fortunately, nobody was injured in the accident.","ru":"К счастью, в аварии никто не пострадал.","vi":"Rất may không có ai bị thương trong vụ tai nạn.","fa":"خوشبختانه در این حادثه به کسی آسیبی نرسید."}]},{"word":"der Unfallgegner","en":"the other party in an accident","ru":"виновник аварии, вторая сторона в ДТП","vi":"bên kia liên quan đến vụ tai nạn","fa":"طرف مقابل درگیر حادثه","examples":[{"de":"Der Unfallgegner war eindeutig schuld an dem Zusammenstoß.","en":"The other party was clearly at fault for the collision.","ru":"В столкновении явно был виноват другой участник.","vi":"Bên kia rõ ràng có lỗi trong vụ va chạm.","fa":"طرف مقابل به وضوح مقصر این برخورد بود."},{"de":"Ich habe mit dem Unfallgegner die Versicherungsdaten ausgetauscht.","en":"I exchanged insurance details with the other party in the accident.","ru":"Я обменялся страховыми данными со вторым участником аварии.","vi":"Tôi đã trao đổi chi tiết bảo hiểm với bên kia trong vụ tai nạn.","fa":"من مشخصات بیمه را با طرف حادثه رد و بدل کردم."},{"de":"Der Unfallgegner fuhr einfach weiter.","en":"The other party in the accident simply drove on.","ru":"Другой участник аварии просто уехал.","vi":"Bên kia liên quan đến vụ tai nạn chỉ đơn giản là tiếp tục lái xe.","fa":"طرف مقابل تصادف به سادگی به رانندگی ادامه داد."}]},{"word":"die Unfallversicherung","en":"accident insurance","ru":"страхование от несчастных случаев","vi":"bảo hiểm tai nạn","fa":"بیمه حوادث","examples":[{"de":"Eine private Unfallversicherung kann sich für Sportler lohnen.","en":"Private accident insurance can be worthwhile for athletes.","ru":"Частное страхование от несчастных случаев может быть выгодно спортсменам.","vi":"Bảo hiểm tai nạn cá nhân có thể có giá trị đối với các vận động viên.","fa":"بیمه حوادث خصوصی می تواند برای ورزشکاران مفید باشد."},{"de":"Die Unfallversicherung übernimmt die Kosten der Behandlung.","en":"The accident insurance covers the cost of the treatment.","ru":"Страхование от несчастных случаев покрывает расходы на лечение.","vi":"Bảo hiểm tai nạn chi trả chi phí điều trị.","fa":"بیمه حوادث هزینه های درمان را پوشش می دهد."},{"de":"Hast du schon eine Unfallversicherung abgeschlossen?","en":"Have you already taken out accident insurance?","ru":"Ты уже оформил страхование от несчастных случаев?","vi":"Bạn đã mua bảo hiểm tai nạn chưa?","fa":"آیا قبلاً بیمه حوادث گرفته اید؟"}]},{"word":"unfreundlich","en":"unfriendly","ru":"неприветливый, недружелюбный","vi":"không thân thiện","fa":"غیر دوستانه","examples":[{"de":"Der Kellner war heute ziemlich unfreundlich.","en":"The waiter was rather unfriendly today.","ru":"Официант был сегодня довольно неприветлив.","vi":"Người phục vụ hôm nay khá thô lỗ.","fa":"گارسون امروز خیلی بی ادب بود."},{"de":"Sei bitte nicht so unfreundlich zu deiner Schwester.","en":"Please don't be so unfriendly to your sister.","ru":"Пожалуйста, не будь так недружелюбна с сестрой.","vi":"Làm ơn đừng đối xử tệ với em gái mình như thế.","fa":"لطفا اینقدر با خواهرت نامهربانی نکن"},{"de":"Das Personal im Hotel war leider sehr unfreundlich.","en":"Unfortunately the hotel staff were very unfriendly.","ru":"К сожалению, персонал отеля был очень неприветлив.","vi":"Thật không may, nhân viên tại khách sạn rất không thân thiện.","fa":"متأسفانه کارکنان هتل بسیار غیر دوستانه بودند."}]},{"word":"ungefähr","en":"approximately, about","ru":"примерно, приблизительно","vi":"xấp xỉ","fa":"تقریبا","examples":[{"de":"Die Fahrt dauert ungefähr zwei Stunden.","en":"The trip takes approximately two hours.","ru":"Поездка занимает примерно два часа.","vi":"Cuộc hành trình mất khoảng hai giờ.","fa":"سفر تقریبا دو ساعت طول می کشد."},{"de":"Ich habe ungefähr hundert Euro dabei.","en":"I have about a hundred euros with me.","ru":"У меня с собой примерно сто евро.","vi":"Tôi mang theo khoảng một trăm euro.","fa":"من حدود صد یورو با خودم دارم."}]},{"word":"ungesund","en":"unhealthy","ru":"нездоровый, вредный для здоровья","vi":"không khỏe mạnh","fa":"ناسالم","examples":[{"de":"Zu viel Zucker ist ungesund.","en":"Too much sugar is unhealthy.","ru":"Слишком много сахара вредно для здоровья.","vi":"Quá nhiều đường không tốt cho sức khỏe.","fa":"قند بیش از حد ناسالم است."},{"de":"Rauchen ist sehr ungesund für die Lunge.","en":"Smoking is very unhealthy for the lungs.","ru":"Курение очень вредно для лёгких.","vi":"Hút thuốc rất có hại cho phổi.","fa":"سیگار کشیدن برای ریه ها بسیار ناسالم است."},{"de":"Es ist ungesund, jeden Tag Fast Food zu essen.","en":"It's unhealthy to eat fast food every day.","ru":"Есть фастфуд каждый день вредно.","vi":"Ăn đồ ăn nhanh hàng ngày không tốt cho sức khỏe.","fa":"خوردن هر روز فست فود ناسالم است."}]},{"word":"ungewöhnlich","en":"unusual","ru":"необычный","vi":"bất thường","fa":"غیر معمول","examples":[{"de":"Das Wetter ist heute ungewöhnlich warm.","en":"The weather is unusually warm today.","ru":"Сегодня погода необычно тёплая.","vi":"Thời tiết hôm nay ấm áp lạ thường.","fa":"امروز هوا به طور غیرعادی گرم است."},{"de":"Sie hatte eine ungewöhnliche Idee.","en":"She had an unusual idea.","ru":"У неё была необычная идея.","vi":"Cô ấy có một ý tưởng khác thường.","fa":"او یک ایده غیر معمول داشت."}]},{"word":"ungewohnt","en":"unaccustomed, unfamiliar, unusual (to one)","ru":"непривычный","vi":"bất thường","fa":"غیر معمول","examples":[{"de":"Die neue Tastatur fühlt sich noch ungewohnt an.","en":"The new keyboard still feels unfamiliar.","ru":"Новая клавиатура пока ощущается непривычно.","vi":"Bàn phím mới vẫn cho cảm giác khác thường.","fa":"صفحه کلید جدید همچنان غیرعادی است."},{"de":"Es war ungewohnt für mich, so früh aufzustehen.","en":"It was unusual for me to get up so early.","ru":"Мне было непривычно вставать так рано.","vi":"Thật là bất thường khi tôi dậy sớm như vậy.","fa":"برای من غیرعادی بود که اینقدر زود بیدار شوم."},{"de":"In der ungewohnten Umgebung konnte er schlecht schlafen.","en":"He slept badly in the unfamiliar surroundings.","ru":"В непривычной обстановке он плохо спал.","vi":"Anh rất khó ngủ trong môi trường xa lạ.","fa":"خوابیدن در محیط ناآشنا برایش سخت بود."}]},{"word":"unglaublich","en":"unbelievable, incredible","ru":"невероятный","vi":"không thể tin được","fa":"باور نکردنی","examples":[{"de":"Das ist ja unglaublich!","en":"That's just unbelievable!","ru":"Это просто невероятно!","vi":"Thật không thể tin được!","fa":"این باور نکردنی است!"},{"de":"Er hat eine unglaubliche Geschichte erzählt.","en":"He told an incredible story.","ru":"Он рассказал невероятную историю.","vi":"Anh ấy đã kể một câu chuyện đáng kinh ngạc.","fa":"او یک داستان باورنکردنی تعریف کرد."}]},{"word":"das Unglück","en":"the accident, misfortune","ru":"несчастье, несчастный случай","vi":"sự bất hạnh","fa":"بدبختی","examples":[{"de":"Bei dem Unglück wurden viele Menschen verletzt.","en":"Many people were injured in the accident.","ru":"В результате несчастного случая пострадало много людей.","vi":"Nhiều người bị thương trong vụ tai nạn.","fa":"در این حادثه افراد زیادی مجروح شدند."},{"de":"Es brachte ihm Unglück, an dem Tag zu reisen.","en":"It brought him bad luck to travel that day.","ru":"Ему принесло несчастье путешествовать в тот день.","vi":"Thật là xui xẻo cho anh ta khi đi du lịch vào ngày hôm đó.","fa":"سفر آن روز برایش بدشانسی بود."}]},{"word":"unheimlich","en":"creepy, eerie; (colloquial) extremely","ru":"жуткий; (разг.) невероятно, очень","vi":"đáng sợ","fa":"ترسناک","examples":[{"de":"Das alte Haus wirkt unheimlich.","en":"The old house seems creepy.","ru":"Старый дом выглядит жутко.","vi":"Ngôi nhà cũ trông thật kỳ lạ.","fa":"خانه قدیمی ترسناک به نظر می رسد."},{"de":"Ich habe mich unheimlich gefreut.","en":"I was extremely happy.","ru":"Я невероятно обрадовался.","vi":"Tôi đã vô cùng hạnh phúc.","fa":"من فوق العاده خوشحال بودم."}]},{"word":"unhöflich","en":"impolite; rude","ru":"невежливый; грубый","vi":"thô lỗ","fa":"بی ادب","examples":[{"de":"Es ist unhöflich, andere zu unterbrechen.","en":"It is rude to interrupt others.","ru":"Невежливо перебивать других.","vi":"Thật thô lỗ khi ngắt lời người khác.","fa":"بی ادبی است که حرف دیگران را قطع کنید."},{"de":"Der Verkäufer war ziemlich unhöflich zu uns.","en":"The salesperson was quite rude to us.","ru":"Продавец был довольно груб с нами.","vi":"Người bán khá thô lỗ với chúng tôi.","fa":"فروشنده نسبت به ما بسیار بی ادب بود."}]},{"word":"die Uniform","en":"the uniform","ru":"форма, униформа","vi":"đồng phục","fa":"لباس فرم","examples":[{"de":"Der Polizist trägt eine Uniform.","en":"The policeman wears a uniform.","ru":"Полицейский носит форму.","vi":"Viên cảnh sát đang mặc đồng phục.","fa":"افسر پلیس یونیفرم پوشیده است."},{"de":"In dieser Schule tragen die Schüler eine Uniform.","en":"In this school the students wear a uniform.","ru":"В этой школе ученики носят форму.","vi":"Ở trường này, học sinh mặc đồng phục.","fa":"در این مدرسه دانش آموزان لباس فرم می پوشند."}]},{"word":"die Universität","en":"the university","ru":"университет","vi":"trường đại học","fa":"دانشگاه","examples":[{"de":"Meine Schwester studiert an der Universität München.","en":"My sister studies at the University of Munich.","ru":"Моя сестра учится в Мюнхенском университете.","vi":"Em gái tôi đang học tại Đại học Munich.","fa":"خواهرم در دانشگاه مونیخ درس می خواند."},{"de":"Er hat gerade sein Studium an der Universität begonnen.","en":"He has just started his studies at the university.","ru":"Он только что начал учёбу в университете.","vi":"Anh ấy mới bắt đầu học tại trường đại học.","fa":"او به تازگی تحصیلات خود را در دانشگاه آغاز کرده است."}]},{"word":"das Universum","en":"universe","ru":"вселенная","vi":"vũ trụ","fa":"کیهان","examples":[{"de":"Das Universum dehnt sich seit dem Urknall immer weiter aus.","en":"The universe has been expanding ever since the Big Bang.","ru":"Вселенная расширяется всё дальше со времён Большого взрыва.","vi":"Vũ trụ đã mở rộng kể từ vụ nổ Big Bang.","fa":"جهان از زمان انفجار بزرگ در حال انبساط بوده است."},{"de":"Niemand weiß genau, wie groß das Universum wirklich ist.","en":"Nobody knows exactly how big the universe really is.","ru":"Никто точно не знает, насколько на самом деле велика вселенная.","vi":"Không ai biết chính xác vũ trụ thực sự lớn đến mức nào.","fa":"هیچ کس دقیقاً نمی داند که جهان واقعاً چقدر بزرگ است."},{"de":"Im Universum gibt es unzählige Galaxien.","en":"There are countless galaxies in the universe.","ru":"Во вселенной существует бесчисленное множество галактик.","vi":"Có vô số thiên hà trong vũ trụ.","fa":"کهکشان های بی شماری در جهان وجود دارد."}]},{"word":"unordentlich","en":"untidy; messy","ru":"неопрятный, неаккуратный","vi":"lộn xộn","fa":"آشفته","examples":[{"de":"Ihr Schreibtisch ist furchtbar unordentlich.","en":"Her desk is terribly untidy.","ru":"Её письменный стол ужасно неопрятный.","vi":"Bàn làm việc của bạn cực kỳ bừa bộn.","fa":"میز شما به طرز وحشتناکی به هم ریخته است."},{"de":"Das Kinderzimmer ist heute besonders unordentlich.","en":"The children's room is especially messy today.","ru":"Детская комната сегодня особенно неаккуратная.","vi":"Phòng trẻ em hôm nay đặc biệt bừa bộn.","fa":"اتاق بچه ها امروزه به خصوص نامرتب است."},{"de":"Ich finde nichts in diesem unordentlichen Schrank.","en":"I can't find anything in this untidy cupboard.","ru":"В этом неопрятном шкафу я ничего не могу найти.","vi":"Tôi không thể tìm thấy bất cứ thứ gì trong tủ quần áo bừa bộn này.","fa":"من در این کمد آشفته چیزی پیدا نمی کنم."}]},{"word":"unregelmäßig","en":"irregular","ru":"нерегулярный, неправильный","vi":"không thường xuyên","fa":"نامنظم","examples":[{"de":"Diese Verben sind unregelmäßig.","en":"These verbs are irregular.","ru":"Эти глаголы неправильные.","vi":"Những động từ này là bất quy tắc.","fa":"این افعال بی قاعده هستند."},{"de":"Sein Herzschlag war plötzlich unregelmäßig.","en":"His heartbeat was suddenly irregular.","ru":"Его сердцебиение вдруг стало неровным.","vi":"Nhịp tim của anh đột nhiên trở nên không đều.","fa":"ضربان قلبش ناگهان نامنظم شد."},{"de":"Die Züge fahren heute leider unregelmäßig.","en":"Unfortunately the trains are running irregularly today.","ru":"К сожалению, сегодня поезда ходят нерегулярно.","vi":"Thật không may, hôm nay tàu chạy không bình thường.","fa":"متاسفانه امروز قطارها به صورت نامنظم حرکت می کنند."}]},{"word":"unsicher","en":"unsure, uncertain; unsafe, insecure","ru":"неуверенный; небезопасный","vi":"không chắc chắn","fa":"نامشخص","examples":[{"de":"Ich bin mir unsicher, ob das die richtige Entscheidung ist.","en":"I'm unsure whether that's the right decision.","ru":"Я не уверен, правильное ли это решение.","vi":"Tôi không chắc đây có phải là quyết định đúng đắn hay không.","fa":"من مطمئن نیستم که آیا این تصمیم درستی است."},{"de":"Die Lage auf dem Arbeitsmarkt ist unsicher.","en":"The situation on the job market is uncertain.","ru":"Ситуация на рынке труда нестабильна.","vi":"Tình hình trên thị trường lao động là không chắc chắn.","fa":"وضعیت بازار کار نامشخص است."},{"de":"Auf dem Eis fühlte er sich unsicher.","en":"He felt unsteady on the ice.","ru":"На льду он чувствовал себя неуверенно.","vi":"Anh ấy cảm thấy không an toàn trên băng.","fa":"او روی یخ احساس ناامنی می کرد."}]},{"word":"unter","en":"under, below; among","ru":"под; среди","vi":"dưới","fa":"زیر","examples":[{"de":"Die Katze schläft unter dem Tisch.","en":"The cat is sleeping under the table.","ru":"Кошка спит под столом.","vi":"Con mèo ngủ dưới gầm bàn.","fa":"گربه زیر میز می خوابد."},{"de":"Unter den Gästen war auch der Bürgermeister.","en":"Among the guests was also the mayor.","ru":"Среди гостей был и мэр.","vi":"Thị trưởng cũng nằm trong số khách mời.","fa":"شهردار نیز در جمع مهمانان حضور داشت."}]},{"word":"unter vier Augen sprechen","en":"to speak privately (one-on-one)","ru":"поговорить с глазу на глаз","vi":"nói chuyện riêng tư","fa":"خصوصی صحبت کردن","examples":[{"de":"Können wir das bitte unter vier Augen besprechen?","en":"Can we please discuss this privately?","ru":"Можем обсудить это с глазу на глаз?","vi":"Chúng ta có thể vui lòng thảo luận chuyện này một cách riêng tư được không?","fa":"آیا می‌توانیم در این مورد در خصوصی صحبت کنیم؟"}]},{"word":"unter-","en":"prefix meaning 'under, sub-'","ru":"приставка со значением 'под-'","vi":"dưới-","fa":"زیر-","examples":[{"de":"Die U-Bahn fährt unterirdisch durch die Stadt.","en":"The subway runs underground through the city.","ru":"Метро проходит под землёй через город.","vi":"Tàu điện ngầm chạy ngầm xuyên qua thành phố.","fa":"مترو از زیر زمین در شهر عبور می کند."},{"de":"Der Tunnel liegt tief unterirdisch.","en":"The tunnel lies deep underground.","ru":"Туннель расположен глубоко под землёй.","vi":"Đường hầm nằm sâu dưới lòng đất.","fa":"تونل در اعماق زمین است."}]},{"word":"unterbrechen","en":"to interrupt","ru":"прерывать","vi":"làm gián đoạn","fa":"قطع کردن","examples":[{"de":"Entschuldigung, darf ich dich kurz unterbrechen?","en":"Excuse me, may I interrupt you briefly?","ru":"Извини, можно я тебя ненадолго прерву?","vi":"Xin lỗi, tôi có thể ngắt lời bạn một lát được không?","fa":"ببخشید میتونم یه لحظه حرفتونو قطع کنم؟"},{"de":"Der Redner wurde mehrmals unterbrochen.","en":"The speaker was interrupted several times.","ru":"Докладчика несколько раз перебивали.","vi":"Người nói bị gián đoạn nhiều lần.","fa":"سخنران چندین بار قطع شد."}]},{"word":"die Unterbringung","en":"accommodation, lodging","ru":"размещение, жильё (для проживания)","vi":"chỗ ở","fa":"محل اقامت","examples":[{"de":"Die Unterbringung im Hotel war sauber und ruhig.","en":"The accommodation in the hotel was clean and quiet.","ru":"Размещение в отеле было чистым и тихим.","vi":"Chỗ ở trong khách sạn sạch sẽ và yên tĩnh.","fa":"محل اقامت در هتل تمیز و آرام بود."},{"de":"Für die Reisegruppe suchen wir eine günstige Unterbringung.","en":"For the travel group we are looking for cheap accommodation.","ru":"Для тургруппы мы ищем недорогое жильё.","vi":"Chúng tôi đang tìm chỗ ở giá cả phải chăng cho nhóm du lịch.","fa":"ما به دنبال اقامتی مقرون به صرفه برای گروه مسافرتی هستیم."},{"de":"Die Unterbringung der Gäste ist bereits organisiert.","en":"The lodging for the guests has already been arranged.","ru":"Размещение гостей уже организовано.","vi":"Chỗ ở của khách đã được sắp xếp sẵn.","fa":"محل اسکان میهمانان از قبل سازماندهی شده است."}]},{"word":"der Untergang","en":"downfall, fall (of an empire)","ru":"падение, гибель (империи, порядка), крах","vi":"sự sụp đổ","fa":"سقوط","examples":[{"de":"Der Untergang des Römischen Reiches dauerte viele Jahre.","en":"The fall of the Roman Empire took many years.","ru":"Падение Римской империи длилось много лет.","vi":"Sự sụp đổ của Đế chế La Mã kéo dài nhiều năm.","fa":"سقوط امپراتوری روم سال ها طول کشید."},{"de":"Historiker diskutieren bis heute die Gründe für den Untergang.","en":"Historians still debate the reasons for the downfall today.","ru":"Историки до сих пор спорят о причинах гибели.","vi":"Các nhà sử học tiếp tục tranh luận về nguyên nhân dẫn đến vụ chìm tàu ​​cho đến ngày nay.","fa":"مورخان به بحث درباره دلایل غرق شدن تا به امروز ادامه می دهند."},{"de":"Der Untergang der Dynastie kam ganz plötzlich.","en":"The downfall of the dynasty came quite suddenly.","ru":"Падение династии произошло совершенно внезапно.","vi":"Sự sụp đổ của triều đại đến bất ngờ.","fa":"سقوط سلسله ناگهان اتفاق افتاد."}]},{"word":"die Unterhaltung","en":"conversation; entertainment","ru":"разговор, беседа; развлечение","vi":"sự giải trí","fa":"سرگرمی","examples":[{"de":"Wir hatten gestern eine lange Unterhaltung über Politik.","en":"We had a long conversation about politics yesterday.","ru":"Вчера у нас был долгий разговор о политике.","vi":"Chúng tôi đã có một cuộc trò chuyện dài về chính trị ngày hôm qua.","fa":"دیروز گفتگوی طولانی درباره سیاست داشتیم."},{"de":"Im Zug sorgte ein Buch für gute Unterhaltung.","en":"On the train a book provided good entertainment.","ru":"В поезде книга была хорошим развлечением.","vi":"Một cuốn sách cung cấp giải trí tốt trên tàu.","fa":"یک کتاب سرگرمی خوبی در قطار فراهم کرد."},{"de":"Die Unterhaltung mit den Gästen war sehr angenehm.","en":"The conversation with the guests was very pleasant.","ru":"Беседа с гостями была очень приятной.","vi":"Cuộc trò chuyện với khách rất vui vẻ.","fa":"گفتگو با مهمانان بسیار دلنشین بود."}]},{"word":"die Unterkunft","en":"the accommodation, lodging","ru":"жильё, ночлег","vi":"chỗ ở","fa":"محل اقامت","examples":[{"de":"Wir haben eine günstige Unterkunft in der Altstadt gefunden.","en":"We found affordable accommodation in the old town.","ru":"Мы нашли недорогое жильё в старом городе.","vi":"Chúng tôi tìm được chỗ ở giá rẻ ở phố cổ.","fa":"اقامتگاه ارزانی در شهر قدیمی پیدا کردیم."},{"de":"Die Unterkunft war sauber und gemütlich.","en":"The accommodation was clean and cozy.","ru":"Жильё было чистым и уютным.","vi":"Chỗ ở sạch sẽ và thoải mái.","fa":"محل اقامت تمیز و راحت بود."}]},{"word":"die Unterkunft buchen","en":"to book accommodation","ru":"бронировать жильё (размещение)","vi":"đặt chỗ ở","fa":"محل اقامت را رزرو کنید","examples":[{"de":"Wir müssen für den Urlaub noch eine Unterkunft buchen.","en":"We still have to book accommodation for the holiday.","ru":"Нам ещё нужно забронировать жильё на отпуск.","vi":"Chúng tôi vẫn cần đặt chỗ ở cho kỳ nghỉ của mình.","fa":"ما هنوز باید برای تعطیلات خود محل اقامت رزرو کنیم."},{"de":"Ich habe die Unterkunft schon online gebucht.","en":"I have already booked the accommodation online.","ru":"Я уже забронировал жильё онлайн.","vi":"Tôi đã đặt chỗ ở trực tuyến rồi.","fa":"من قبلاً اقامتگاه را به صورت آنلاین رزرو کرده ام."},{"de":"Man sollte die Unterkunft früh buchen, sonst ist alles voll.","en":"You should book accommodation early, otherwise everything is full.","ru":"Жильё стоит бронировать заранее, иначе всё будет занято.","vi":"Bạn nên đặt chỗ ở sớm nếu không mọi thứ sẽ full chỗ.","fa":"شما باید محل اقامت خود را زودتر رزرو کنید وگرنه همه چیز پر خواهد شد."}]},{"word":"die Unterkunftssuche","en":"search for accommodation","ru":"поиск жилья (для проживания)","vi":"việc tìm kiếm chỗ ở","fa":"جستجو برای مسکن","examples":[{"de":"Die Unterkunftssuche war in der Hochsaison schwierig.","en":"Finding accommodation was difficult in the high season.","ru":"Поиск жилья в высокий сезон был трудным.","vi":"Tìm chỗ ở vào mùa cao điểm rất khó khăn.","fa":"یافتن محل اقامت در فصل های بالا دشوار بود."},{"de":"Wir haben die Unterkunftssuche dem Reisebüro überlassen.","en":"We left the search for accommodation to the travel agency.","ru":"Поиск жилья мы поручили турагентству.","vi":"Chúng tôi giao việc tìm chỗ ở cho công ty du lịch.","fa":"جستجوی اقامتگاه را به آژانس مسافرتی واگذار کردیم."},{"de":"Bei der Unterkunftssuche hilft oft das Internet.","en":"The internet often helps with the search for accommodation.","ru":"В поиске жилья часто помогает интернет.","vi":"Internet thường hữu ích khi tìm kiếm chỗ ở.","fa":"اینترنت اغلب هنگام جستجوی محل اقامت مفید است."}]},{"word":"die Unterlage","en":"document; mat, pad, base","ru":"документ (бумага); подставка, коврик, основа","vi":"lớp lót","fa":"زیرانداز","examples":[{"de":"Leg bitte eine Unterlage unter den Topf, damit der Tisch nicht heiß wird.","en":"Please put a mat under the pot so the table doesn't get hot.","ru":"Пожалуйста, подложи под кастрюлю подставку, чтобы стол не нагрелся.","vi":"Hãy đặt một bề mặt dưới nồi để bàn không bị nóng.","fa":"لطفا سطحی زیر قابلمه قرار دهید تا میز داغ نشود."},{"de":"Eine wichtige Unterlage fehlt noch in der Bewerbung.","en":"One important document is still missing from the application.","ru":"В заявке всё ещё не хватает одного важного документа.","vi":"Một tài liệu quan trọng vẫn còn thiếu trong đơn đăng ký.","fa":"یک سند مهم هنوز در برنامه وجود ندارد."},{"de":"Für das Yoga brauchst du eine weiche Unterlage.","en":"For yoga you need a soft mat.","ru":"Для йоги нужен мягкий коврик.","vi":"Bạn cần một bề mặt mềm mại để tập yoga.","fa":"برای یوگا به یک سطح نرم نیاز دارید."}]},{"word":"die Unterlagen","en":"the documents, papers","ru":"документы","vi":"các tài liệu","fa":"اسناد","examples":[{"de":"Bitte bringen Sie alle nötigen Unterlagen mit.","en":"Please bring all the necessary documents.","ru":"Пожалуйста, принесите все необходимые документы.","vi":"Vui lòng mang theo tất cả các tài liệu cần thiết với bạn.","fa":"لطفا تمام مدارک لازم را همراه داشته باشید."},{"de":"Ich habe meine Unterlagen für die Bewerbung vorbereitet.","en":"I've prepared my documents for the application.","ru":"Я подготовил свои документы для заявки.","vi":"Tôi đã chuẩn bị đầy đủ hồ sơ để nộp đơn.","fa":"من مدارکم را برای درخواست آماده کرده ام."}]},{"word":"unterlassen","en":"to refrain from, omit doing","ru":"воздерживаться (от чего-л.)","vi":"kiềm chế","fa":"خودداری از","examples":[{"de":"Bitte unterlassen Sie das Rauchen hier.","en":"Please refrain from smoking here.","ru":"Пожалуйста, воздержитесь здесь от курения.","vi":"Vui lòng không hút thuốc ở đây.","fa":"لطفا در اینجا از کشیدن سیگار خودداری کنید."},{"de":"Er hat es unterlassen, mich zu informieren.","en":"He failed to inform me.","ru":"Он не удосужился сообщить мне.","vi":"Anh ấy đã quên thông báo cho tôi.","fa":"از اطلاع دادن من غافل شد."}]},{"word":"unternehmen","en":"to undertake, do (an activity)","ru":"предпринимать","vi":"công ty","fa":"شرکت","examples":[{"de":"Was wollen wir heute Abend unternehmen?","en":"What do we want to do tonight?","ru":"Чем мы займёмся сегодня вечером?","vi":"Chúng ta muốn làm gì tối nay?","fa":"امروز عصر می خواهیم چه کنیم؟"},{"de":"Die Regierung muss endlich etwas unternehmen.","en":"The government must finally take action.","ru":"Правительство должно наконец что-то предпринять.","vi":"Chính phủ cuối cùng phải làm điều gì đó.","fa":"بالاخره دولت باید کاری بکند."}]},{"word":"der Unternehmer","en":"entrepreneur, businessman","ru":"предприниматель","vi":"doanh nhân","fa":"کارآفرین","examples":[{"de":"Als junger Unternehmer hat er eine eigene Firma gegründet.","en":"As a young entrepreneur he founded his own company.","ru":"Молодым предпринимателем он основал собственную фирму.","vi":"Là một doanh nhân trẻ, anh đã thành lập công ty riêng của mình.","fa":"او به عنوان یک کارآفرین جوان، شرکت خود را تأسیس کرد."},{"de":"Der Unternehmer beschäftigt über hundert Mitarbeiter.","en":"The businessman employs over a hundred staff.","ru":"У предпринимателя работает более ста сотрудников.","vi":"Doanh nhân này tuyển dụng hơn một trăm người.","fa":"این کارآفرین بیش از صد نفر را استخدام می کند."},{"de":"Ein erfolgreicher Unternehmer muss Risiken eingehen.","en":"A successful entrepreneur has to take risks.","ru":"Успешный предприниматель должен идти на риск.","vi":"Một doanh nhân thành công phải chấp nhận rủi ro.","fa":"یک کارآفرین موفق باید ریسک کند."}]},{"word":"die Unternehmerin","en":"the (female) entrepreneur, businesswoman","ru":"предпринимательница","vi":"doanh nhân","fa":"کارآفرین","examples":[{"de":"Sie ist eine erfolgreiche Unternehmerin.","en":"She is a successful entrepreneur.","ru":"Она успешная предпринимательница.","vi":"Cô ấy là một doanh nhân thành đạt.","fa":"او یک کارآفرین موفق است."},{"de":"Die Unternehmerin hat vor fünf Jahren ihre eigene Firma gegründet.","en":"The businesswoman founded her own company five years ago.","ru":"Предпринимательница основала свою компанию пять лет назад.","vi":"Nữ doanh nhân này đã thành lập công ty riêng của mình cách đây 5 năm.","fa":"این کارآفرین پنج سال پیش شرکت خود را تأسیس کرد."}]},{"word":"unterrichten","en":"to teach","ru":"преподавать","vi":"dạy","fa":"آموزش دهید","examples":[{"de":"Sie unterrichtet Mathematik an einem Gymnasium.","en":"She teaches math at a high school.","ru":"Она преподаёт математику в гимназии.","vi":"Cô dạy toán ở một trường trung học.","fa":"او در دبیرستان ریاضیات تدریس می کند."},{"de":"Wer unterrichtet euch in Deutsch?","en":"Who teaches you German?","ru":"Кто преподаёт вам немецкий?","vi":"Ai dạy bạn tiếng Đức?","fa":"چه کسی به شما آلمانی یاد می دهد؟"}]},{"word":"untersagt","en":"forbidden, prohibited","ru":"запрещено","vi":"bị cấm","fa":"ممنوع است","examples":[{"de":"Das Fotografieren ist hier untersagt.","en":"Photography is prohibited here.","ru":"Фотографировать здесь запрещено.","vi":"Chụp ảnh bị cấm ở đây.","fa":"عکاسی در اینجا ممنوع است."},{"de":"Der Zutritt für Unbefugte ist untersagt.","en":"Access for unauthorized persons is forbidden.","ru":"Вход посторонним запрещён.","vi":"Truy cập cho những người không có thẩm quyền đều bị cấm.","fa":"دسترسی افراد غیر مجاز ممنوع است."}]},{"word":"unterscheiden","en":"to distinguish, differentiate","ru":"различать","vi":"phân biệt","fa":"متمایز کردن","examples":[{"de":"Kannst du diese beiden Weine unterscheiden?","en":"Can you distinguish between these two wines?","ru":"Можешь различить эти два вина?","vi":"Bạn có thể phân biệt được hai loại rượu này không?","fa":"آیا می توانید این دو شراب را از هم جدا کنید؟"},{"de":"Die Zwillinge sind kaum zu unterscheiden.","en":"The twins are hardly distinguishable.","ru":"Близнецов едва можно различить.","vi":"Cặp song sinh khó có thể được phân biệt.","fa":"دوقلوها به سختی قابل تشخیص هستند."}]},{"word":"unterschiedlich","en":"different; varying","ru":"различный; разный","vi":"khác nhau","fa":"متفاوت است","examples":[{"de":"Die Meinungen dazu sind sehr unterschiedlich.","en":"Opinions on this vary widely.","ru":"Мнения по этому поводу очень разные.","vi":"Các ý kiến ​​về điều này rất khác nhau.","fa":"نظرات در این مورد بسیار متفاوت است."},{"de":"Die Zwillinge haben ganz unterschiedliche Charaktere.","en":"The twins have completely different characters.","ru":"У близнецов совершенно разные характеры.","vi":"Cặp song sinh có tính cách rất khác nhau.","fa":"دوقلوها شخصیت های بسیار متفاوتی دارند."}]},{"word":"unterschreiben","en":"to sign","ru":"подписывать","vi":"ký tên","fa":"علامت بزنید","examples":[{"de":"Bitte unterschreiben Sie hier unten.","en":"Please sign here at the bottom.","ru":"Пожалуйста, подпишите здесь внизу.","vi":"Vui lòng ký tên bên dưới.","fa":"لطفا زیر را امضا کنید"},{"de":"Ich habe den Vertrag noch nicht unterschrieben.","en":"I haven't signed the contract yet.","ru":"Я ещё не подписал договор.","vi":"Tôi vẫn chưa ký hợp đồng.","fa":"من هنوز قرارداد را امضا نکرده ام."}]},{"word":"die Unterschrift","en":"the signature","ru":"подпись","vi":"chữ ký","fa":"امضا","examples":[{"de":"Ich brauche noch Ihre Unterschrift.","en":"I still need your signature.","ru":"Мне ещё нужна ваша подпись.","vi":"Tôi vẫn cần chữ ký của bạn.","fa":"من هنوز به امضای شما نیاز دارم"},{"de":"Ohne Unterschrift ist das Dokument ungültig.","en":"Without a signature the document is invalid.","ru":"Без подписи документ недействителен.","vi":"Không có chữ ký, tài liệu không hợp lệ.","fa":"بدون امضا سند نامعتبر است."}]},{"word":"unterstreichen","en":"to underline","ru":"подчёркивать","vi":"gạch chân","fa":"زیر خط بکش","examples":[{"de":"Unterstreiche die wichtigen Wörter im Text.","en":"Underline the important words in the text.","ru":"Подчеркни важные слова в тексте.","vi":"Gạch dưới những từ quan trọng trong văn bản.","fa":"زیر کلمات مهم متن خط بکشید."},{"de":"Der Lehrer hat die Fehler rot unterstrichen.","en":"The teacher underlined the mistakes in red.","ru":"Учитель подчеркнул ошибки красным.","vi":"Giáo viên gạch chân những lỗi sai bằng cách tô đỏ.","fa":"معلم زیر اشتباهات قرمز خط کشید."}]},{"word":"unterstützen","en":"to support","ru":"поддерживать","vi":"hỗ trợ","fa":"پشتیبانی کنید","examples":[{"de":"Meine Eltern unterstützen mich finanziell.","en":"My parents support me financially.","ru":"Мои родители поддерживают меня финансово.","vi":"Bố mẹ tôi hỗ trợ tôi về mặt tài chính.","fa":"پدر و مادرم از من حمایت مالی می کنند."},{"de":"Wir unterstützen dieses Projekt seit Jahren.","en":"We have been supporting this project for years.","ru":"Мы поддерживаем этот проект уже много лет.","vi":"Chúng tôi đã hỗ trợ dự án này trong nhiều năm.","fa":"ما سال ها از این پروژه حمایت می کنیم."}]},{"word":"die Unterstützung","en":"the support","ru":"поддержка","vi":"sự hỗ trợ","fa":"پشتیبانی","examples":[{"de":"Vielen Dank für Ihre Unterstützung!","en":"Thank you very much for your support!","ru":"Большое спасибо за вашу поддержку!","vi":"Cảm ơn sự hỗ trợ của bạn!","fa":"از حمایت شما متشکرم"},{"de":"Ohne die Unterstützung meiner Familie hätte ich es nicht geschafft.","en":"Without my family's support I wouldn't have made it.","ru":"Без поддержки своей семьи я бы не справился.","vi":"Tôi không thể làm được điều đó nếu không có sự hỗ trợ của gia đình.","fa":"بدون حمایت خانواده ام نمی توانستم این کار را انجام دهم."}]},{"word":"untersuchen","en":"to examine, investigate","ru":"исследовать, обследовать","vi":"điều tra","fa":"بررسی کنید","examples":[{"de":"Der Arzt hat mich gründlich untersucht.","en":"The doctor examined me thoroughly.","ru":"Врач тщательно меня осмотрел.","vi":"Bác sĩ đã khám cho tôi rất kỹ.","fa":"دکتر مرا به طور کامل معاینه کرد."},{"de":"Die Polizei untersucht den Fall genau.","en":"The police are investigating the case closely.","ru":"Полиция тщательно расследует это дело.","vi":"Cảnh sát đang điều tra vụ việc chặt chẽ.","fa":"پلیس در حال بررسی دقیق این پرونده است."}]},{"word":"die Untersuchung","en":"examination; investigation","ru":"обследование; исследование","vi":"cuộc điều tra","fa":"تحقیق","examples":[{"de":"Der Arzt empfiehlt eine gründliche Untersuchung.","en":"The doctor recommends a thorough examination.","ru":"Врач рекомендует тщательное обследование.","vi":"Bác sĩ đề nghị kiểm tra kỹ lưỡng.","fa":"پزشک معاینه کامل را توصیه می کند."},{"de":"Die Untersuchung des Unfalls dauert noch an.","en":"The investigation into the accident is still ongoing.","ru":"Расследование аварии всё ещё продолжается.","vi":"Cuộc điều tra về vụ tai nạn vẫn đang được tiếp tục.","fa":"تحقیقات درباره این حادثه همچنان ادامه دارد."}]},{"word":"der Untertitel","en":"subtitle","ru":"субтитры","vi":"phụ đề","fa":"زیرنویس","examples":[{"de":"Ich schaue ausländische Filme gern mit Untertiteln.","en":"I like watching foreign films with subtitles.","ru":"Я люблю смотреть иностранные фильмы с субтитрами.","vi":"Tôi thích xem phim nước ngoài có phụ đề.","fa":"تماشای فیلم های خارجی با زیرنویس را دوست دارم."},{"de":"Kannst du die Untertitel einschalten? Ich verstehe ihn schlecht.","en":"Can you turn on the subtitles? I can't understand him well.","ru":"Можешь включить субтитры? Я плохо его понимаю.","vi":"Bạn có thể bật phụ đề được không? Tôi không hiểu rõ về anh ấy.","fa":"میشه زیرنویس رو روشن کنی من او را خوب درک نمی کنم."},{"de":"Der Film hat deutsche Untertitel für Gehörlose.","en":"The film has German subtitles for the deaf.","ru":"У фильма есть немецкие субтитры для глухих.","vi":"Phim có phụ đề tiếng Đức dành cho người khiếm thính.","fa":"این فیلم دارای زیرنویس آلمانی برای ناشنوایان است."}]},{"word":"unterwegs","en":"on the way, out and about","ru":"в пути, в дороге","vi":"trên đường","fa":"در راه","examples":[{"de":"Wir sind schon seit Stunden unterwegs.","en":"We've been on the road for hours already.","ru":"Мы уже несколько часов в пути.","vi":"Chúng tôi đã đi du lịch hàng giờ liền.","fa":"ما ساعت ها در سفر بودیم."},{"de":"Er ist beruflich viel unterwegs.","en":"He travels a lot for work.","ru":"Он много ездит по работе.","vi":"Anh ấy đi công tác rất nhiều.","fa":"او برای کار زیاد سفر می کند."}]},{"word":"unverbindlich","en":"non-binding, without obligation","ru":"необязательный, без обязательств","vi":"không ràng buộc","fa":"غیر الزام آور","examples":[{"de":"Das Angebot ist völlig unverbindlich.","en":"The offer is entirely without obligation.","ru":"Предложение совершенно ни к чему не обязывает.","vi":"Lời đề nghị này hoàn toàn không có tính ràng buộc.","fa":"پیشنهاد کاملا غیر الزام آور است."},{"de":"Fordern Sie ein unverbindliches Angebot an.","en":"Request a non-binding quote.","ru":"Запросите необязывающее предложение.","vi":"Yêu cầu một đề nghị không ràng buộc.","fa":"درخواست یک پیشنهاد غیر الزام آور"},{"de":"Die Beratung ist kostenlos und unverbindlich.","en":"The consultation is free and without obligation.","ru":"Консультация бесплатна и ни к чему не обязывает.","vi":"Việc tư vấn là miễn phí và không ràng buộc.","fa":"مشاوره رایگان و غیر الزام آور می باشد."}]},{"word":"das Update","en":"update","ru":"обновление, апдейт","vi":"bản cập nhật","fa":"the update","examples":[{"de":"Nach dem Update funktioniert die Kamera endlich wieder.","en":"After the update the camera finally works again.","ru":"После обновления камера наконец снова работает.","vi":"Sau khi cập nhật, camera cuối cùng cũng hoạt động trở lại.","fa":"پس از به روز رسانی، دوربین در نهایت دوباره کار می کند."},{"de":"Das Update bringt mehrere neue Funktionen mit.","en":"The update brings several new features with it.","ru":"Обновление приносит с собой несколько новых функций.","vi":"Bản cập nhật mang đến một số tính năng mới.","fa":"The update brings several new features."},{"de":"Vergiss nicht, vor dem Update deine Daten zu sichern.","en":"Don't forget to back up your data before the update.","ru":"Не забудь сделать резервную копию данных перед обновлением.","vi":"Đừng quên sao lưu dữ liệu của bạn trước khi cập nhật.","fa":"فراموش نکنید که قبل از به روز رسانی از اطلاعات خود نسخه پشتیبان تهیه کنید."}]},{"word":"die Urkunde","en":"the certificate, document","ru":"грамота, свидетельство","vi":"giấy chứng nhận","fa":"گواهی","examples":[{"de":"Für den Sieg bekam er eine Urkunde.","en":"He got a certificate for winning.","ru":"За победу он получил грамоту.","vi":"Anh đã nhận được giấy chứng nhận chiến thắng.","fa":"او برای این پیروزی گواهینامه دریافت کرد."},{"de":"Die Urkunde wurde von der Stadt ausgestellt.","en":"The certificate was issued by the city.","ru":"Свидетельство было выдано городом.","vi":"Giấy chứng nhận do thành phố cấp.","fa":"این گواهی توسط شهرستان صادر شده است."}]},{"word":"der Urlaub","en":"the vacation, holiday","ru":"отпуск","vi":"kỳ nghỉ","fa":"تعطیلات","examples":[{"de":"Wir fahren im Sommer in den Urlaub.","en":"We're going on vacation in the summer.","ru":"Летом мы едем в отпуск.","vi":"Chúng tôi đang đi nghỉ vào mùa hè.","fa":"ما در تابستان به تعطیلات می رویم."},{"de":"Wie viele Tage Urlaub hast du dieses Jahr?","en":"How many vacation days do you have this year?","ru":"Сколько дней отпуска у тебя в этом году?","vi":"Năm nay bạn có bao nhiêu ngày nghỉ phép?","fa":"امسال چند روز مرخصی دارید؟"}]},{"word":"die Ursache","en":"the cause, reason","ru":"причина","vi":"nguyên nhân","fa":"علت","examples":[{"de":"Die Ursache des Feuers ist noch unbekannt.","en":"The cause of the fire is still unknown.","ru":"Причина пожара пока неизвестна.","vi":"Hiện vẫn chưa rõ nguyên nhân vụ cháy.","fa":"علت آتش سوزی هنوز مشخص نیست."},{"de":"Man konnte die Ursache des Problems nicht finden.","en":"They couldn't find the cause of the problem.","ru":"Не удалось найти причину проблемы.","vi":"Nguyên nhân của vấn đề không thể được tìm thấy.","fa":"علت مشکل پیدا نشد."}]},{"word":"ursprünglich","en":"originally","ru":"изначально, первоначально","vi":"ban đầu","fa":"در اصل","examples":[{"de":"Ursprünglich wollten wir nach Italien fahren.","en":"Originally we wanted to go to Italy.","ru":"Изначально мы хотели поехать в Италию.","vi":"Ban đầu chúng tôi muốn đến Ý.","fa":"در ابتدا می خواستیم به ایتالیا برویم."},{"de":"Das Haus sah ursprünglich ganz anders aus.","en":"The house originally looked completely different.","ru":"Изначально дом выглядел совершенно иначе.","vi":"Ngôi nhà ban đầu trông hoàn toàn khác.","fa":"خانه در ابتدا کاملاً متفاوت به نظر می رسید."}]},{"word":"das Urteil","en":"the verdict, judgment","ru":"приговор, суждение","vi":"bản án","fa":"حکم","examples":[{"de":"Das Gericht hat sein Urteil gefällt.","en":"The court has passed its verdict.","ru":"Суд вынес свой приговор.","vi":"Tòa án đã đưa ra phán quyết của mình.","fa":"دادگاه حکم خود را داده است."},{"de":"Ich möchte mir kein Urteil über ihn erlauben.","en":"I don't want to allow myself to judge him.","ru":"Я не хочу позволять себе судить о нём.","vi":"Tôi không muốn phán xét anh ấy.","fa":"من نمی خواهم او را قضاوت کنم."}]},{"word":"der Vandalismus","en":"vandalism","ru":"вандализм","vi":"sự phá hoại","fa":"وندالیسم","examples":[{"de":"Der Vandalismus in der U-Bahn nimmt leider zu.","en":"Vandalism in the underground is unfortunately increasing.","ru":"Вандализм в метро, к сожалению, растёт.","vi":"Thật không may, nạn phá hoại ở tàu điện ngầm ngày càng gia tăng.","fa":"متاسفانه خرابکاری در مترو در حال افزایش است."},{"de":"Die zerstörte Bushaltestelle ist ein Fall von Vandalismus.","en":"The destroyed bus stop is a case of vandalism.","ru":"Разрушенная остановка — это случай вандализма.","vi":"Trạm xe buýt bị phá hủy là một trường hợp phá hoại.","fa":"ایستگاه اتوبوس تخریب شده یک مورد خرابکاری است."},{"de":"Gegen den Vandalismus im Park wurden Kameras installiert.","en":"Cameras were installed to combat the vandalism in the park.","ru":"Для борьбы с вандализмом в парке установили камеры.","vi":"Camera được lắp đặt để chống phá hoại trong công viên.","fa":"دوربین هایی برای مبارزه با خرابکاری در پارک نصب شد."}]},{"word":"die Variable","en":"variable","ru":"переменная","vi":"biến","fa":"متغیر","examples":[{"de":"In der Algebra steht ein Buchstabe für eine Variable.","en":"In algebra a letter stands for a variable.","ru":"В алгебре буква обозначает переменную.","vi":"Trong đại số, một chữ cái đại diện cho một biến.","fa":"در جبر، یک حرف نشان دهنده یک متغیر است."},{"de":"Die Variable x ist hier noch unbekannt.","en":"The variable x is still unknown here.","ru":"Переменная x здесь ещё неизвестна.","vi":"Biến x vẫn chưa được biết ở đây.","fa":"متغیر x هنوز در اینجا ناشناخته است."},{"de":"Setze für die Variable eine Zahl ein.","en":"Substitute a number for the variable.","ru":"Подставь вместо переменной число.","vi":"Chèn một số cho biến.","fa":"یک عدد برای متغیر درج کنید."}]},{"word":"die Vase","en":"the vase","ru":"ваза","vi":"cái bình","fa":"گلدان","examples":[{"de":"Sie stellte die Blumen in eine Vase.","en":"She put the flowers in a vase.","ru":"Она поставила цветы в вазу.","vi":"Cô cắm hoa vào bình.","fa":"او گل ها را در گلدان گذاشت."},{"de":"Die Vase ist aus Glas und sehr zerbrechlich.","en":"The vase is made of glass and very fragile.","ru":"Ваза стеклянная и очень хрупкая.","vi":"Chiếc bình được làm bằng thủy tinh và rất dễ vỡ.","fa":"گلدان شیشه ای است و بسیار شکننده است."}]},{"word":"der Vater","en":"the father","ru":"отец","vi":"người cha","fa":"پدر","examples":[{"de":"Mein Vater arbeitet als Lehrer.","en":"My father works as a teacher.","ru":"Мой отец работает учителем.","vi":"Bố tôi làm giáo viên.","fa":"پدرم به عنوان معلم کار می کند."},{"de":"Er ist stolz auf seinen Vater.","en":"He is proud of his father.","ru":"Он гордится своим отцом.","vi":"Anh ấy tự hào về cha mình.","fa":"او به پدرش افتخار می کند."}]},{"word":"der Veganer","en":"vegan (male)","ru":"веган (мужчина)","vi":"người ăn chay","fa":"گیاهخوار","examples":[{"de":"Als Veganer isst er keine tierischen Produkte.","en":"As a vegan he eats no animal products.","ru":"Как веган он не ест никаких продуктов животного происхождения.","vi":"Là một người ăn chay, anh ấy không ăn bất kỳ sản phẩm động vật nào.","fa":"او به عنوان یک گیاهخوار، هیچ محصول حیوانی نمی خورد."},{"de":"Mein Bruder ist seit zwei Jahren Veganer.","en":"My brother has been a vegan for two years.","ru":"Мой брат уже два года веган.","vi":"Anh trai tôi đã ăn chay được hai năm.","fa":"برادر من دو سال است که گیاهخوار است."},{"de":"Für Veganer gibt es in diesem Restaurant viele Gerichte.","en":"There are many dishes for vegans in this restaurant.","ru":"В этом ресторане много блюд для веганов.","vi":"Có rất nhiều món ăn dành cho người ăn chay ở nhà hàng này.","fa":"در این رستوران غذاهای زیادی برای وگان ها وجود دارد."}]},{"word":"der Vegetarier","en":"vegetarian (male)","ru":"вегетарианец (мужчина)","vi":"người ăn chay","fa":"گیاهخوار","examples":[{"de":"Als Vegetarier esse ich kein Fleisch, aber Käse und Eier.","en":"As a vegetarian I don't eat meat, but I do eat cheese and eggs.","ru":"Как вегетарианец я не ем мясо, но ем сыр и яйца.","vi":"Là người ăn chay, tôi không ăn thịt mà ăn phô mai và trứng.","fa":"من به عنوان یک گیاهخوار، گوشت نمی خورم، اما پنیر و تخم مرغ می خورم."},{"de":"Gibt es hier auch ein Gericht für Vegetarier?","en":"Is there also a dish for vegetarians here?","ru":"Здесь есть блюдо и для вегетарианцев?","vi":"Ở đây cũng có món dành cho người ăn chay à?","fa":"آیا در اینجا غذای مخصوص گیاهخواران نیز وجود دارد؟"},{"de":"Mein Kollege ist seit seiner Jugend Vegetarier.","en":"My colleague has been a vegetarian since his youth.","ru":"Мой коллега — вегетарианец с юности.","vi":"Đồng nghiệp của tôi đã ăn chay từ khi còn là một thiếu niên.","fa":"همکار من از نوجوانی گیاهخوار بوده است."}]},{"word":"vegetarisch","en":"vegetarian","ru":"вегетарианский","vi":"ăn chay","fa":"گیاهخواری","examples":[{"de":"Ich esse seit einem Jahr vegetarisch.","en":"I've been eating vegetarian for a year.","ru":"Я уже год питаюсь вегетариански.","vi":"Tôi đã ăn chay được một năm.","fa":"من یک سال است که گیاهخواری می کنم."},{"de":"Das Restaurant bietet auch vegetarische Gerichte an.","en":"The restaurant also offers vegetarian dishes.","ru":"Ресторан также предлагает вегетарианские блюда.","vi":"Nhà hàng còn cung cấp các món ăn chay.","fa":"این رستوران غذاهای گیاهی نیز ارائه می دهد."}]},{"word":"das Velo","en":"the bicycle (Swiss German)","ru":"велосипед (в швейцарском варианте немецкого)","vi":"chiếc xe đạp","fa":"دوچرخه","examples":[{"de":"In der Schweiz sagt man 'Velo' statt 'Fahrrad'.","en":"In Switzerland people say 'Velo' instead of 'Fahrrad'.","ru":"В Швейцарии говорят 'Velo' вместо 'Fahrrad'.","vi":"Ở Thụy Sĩ chúng tôi nói 'velo' thay vì 'xe đạp'.","fa":"در سوئیس به جای «دوچرخه» «velo» می گوییم."},{"de":"Ich fahre jeden Tag mit dem Velo zur Arbeit.","en":"I ride my bike to work every day.","ru":"Я каждый день езжу на велосипеде на работу.","vi":"Tôi đạp xe đi làm hàng ngày.","fa":"من هر روز با دوچرخه به سر کار می روم."}]},{"word":"die Verabredung","en":"arrangement, date (to meet)","ru":"договорённость о встрече, свидание","vi":"cuộc hẹn","fa":"قرار ملاقات","examples":[{"de":"Ich habe heute Abend eine Verabredung.","en":"I have an arrangement to meet someone this evening.","ru":"У меня сегодня вечером назначена встреча.","vi":"Tối nay tôi có hẹn.","fa":"من امشب قرار دارم"},{"de":"Leider muss ich unsere Verabredung absagen.","en":"Unfortunately I have to cancel our arrangement.","ru":"К сожалению, мне придётся отменить нашу встречу.","vi":"Thật không may là tôi phải hủy cuộc hẹn của chúng ta.","fa":"متأسفانه باید قرارمان را لغو کنم."},{"de":"Wir haben eine Verabredung zum Mittagessen.","en":"We have an arrangement to meet for lunch.","ru":"У нас договорённость о совместном обеде.","vi":"Chúng ta có hẹn ăn trưa.","fa":"قرار ناهار داریم"}]},{"word":"verändern","en":"to change, to alter","ru":"изменять, менять","vi":"thay đổi","fa":"تغییر دهید","examples":[{"de":"Der Umzug hat unser Leben völlig verändert.","en":"The move completely changed our lives.","ru":"Переезд полностью изменил нашу жизнь.","vi":"Việc di chuyển đã thay đổi hoàn toàn cuộc sống của chúng tôi.","fa":"این حرکت زندگی ما را به کلی تغییر داد."},{"de":"Du hast dich in den letzten Jahren kaum verändert.","en":"You have hardly changed over the past few years.","ru":"За последние годы ты почти не изменился.","vi":"Bạn không thay đổi nhiều trong vài năm qua.","fa":"شما در چند سال گذشته تغییر چندانی نکرده اید."},{"de":"Wir möchten die Welt zum Besseren verändern.","en":"We want to change the world for the better.","ru":"Мы хотим изменить мир к лучшему.","vi":"Chúng tôi muốn thay đổi thế giới tốt đẹp hơn.","fa":"ما می خواهیم دنیا را به سمت بهتر شدن تغییر دهیم."}]},{"word":"die Veränderung","en":"change","ru":"изменение, перемена","vi":"sự thay đổi","fa":"تغییر","examples":[{"de":"Die Veränderung am Arbeitsplatz war für alle spürbar.","en":"The change at the workplace was noticeable to everyone.","ru":"Изменение на рабочем месте заметили все.","vi":"Mọi người đều có thể nhận thấy sự thay đổi ở nơi làm việc.","fa":"تغییر در محل کار برای همه محسوس بود."},{"de":"Ich brauche eine Veränderung in meinem Leben.","en":"I need a change in my life.","ru":"Мне нужна перемена в жизни.","vi":"Tôi cần một sự thay đổi trong cuộc sống của tôi.","fa":"من نیاز به تغییر در زندگی ام دارم."},{"de":"Diese Veränderung hat viele positive Folgen.","en":"This change has many positive consequences.","ru":"У этого изменения много положительных последствий.","vi":"Sự thay đổi này mang lại nhiều hệ quả tích cực.","fa":"این تغییر پیامدهای مثبت بسیاری دارد."}]},{"word":"die Veranstaltung","en":"the event","ru":"мероприятие","vi":"sự kiện","fa":"رویداد","examples":[{"de":"Die Veranstaltung findet im Stadtpark statt.","en":"The event takes place in the city park.","ru":"Мероприятие проходит в городском парке.","vi":"Sự kiện diễn ra tại công viên thành phố.","fa":"این رویداد در پارک شهر برگزار می شود."},{"de":"Viele Besucher kamen zu der Veranstaltung.","en":"Many visitors came to the event.","ru":"На мероприятие пришло много посетителей.","vi":"Rất nhiều du khách đã đến tham dự sự kiện.","fa":"بازدیدکنندگان زیادی به این رویداد آمدند."}]},{"word":"verantwortlich","en":"responsible","ru":"ответственный","vi":"chịu trách nhiệm","fa":"مسئول","examples":[{"de":"Wer ist für dieses Projekt verantwortlich?","en":"Who is responsible for this project?","ru":"Кто отвечает за этот проект?","vi":"Ai chịu trách nhiệm cho dự án này?","fa":"چه کسی مسئول این پروژه است؟"},{"de":"Sie fühlt sich für ihre Mitarbeiter verantwortlich.","en":"She feels responsible for her employees.","ru":"Она чувствует ответственность за своих сотрудников.","vi":"Cô ấy cảm thấy có trách nhiệm với nhân viên của mình.","fa":"او نسبت به کارمندان خود احساس مسئولیت می کند."}]},{"word":"die Verantwortlichkeit","en":"responsibility, accountability","ru":"ответственность, подотчётность","vi":"trách nhiệm","fa":"مسئولیت","examples":[{"de":"Jeder trägt seine Verantwortlichkeit.","en":"Everyone bears their own responsibility.","ru":"Каждый несёт свою ответственность.","vi":"Mọi người đều có trách nhiệm riêng của mình.","fa":"هر کسی مسئولیت خودش را دارد."},{"de":"Die Verantwortlichkeit liegt bei der Regierung.","en":"The accountability lies with the government.","ru":"Ответственность лежит на правительстве.","vi":"Trách nhiệm thuộc về chính phủ.","fa":"مسئولیت بر عهده دولت است."},{"de":"Mehr Verantwortlichkeit wird gefordert.","en":"More accountability is demanded.","ru":"Требуется больше ответственности.","vi":"Cần có thêm trách nhiệm.","fa":"پاسخگویی بیشتری لازم است."}]},{"word":"die Verantwortung","en":"responsibility","ru":"ответственность","vi":"trách nhiệm","fa":"مسئولیت","examples":[{"de":"Als Chef trägt er die Verantwortung für das ganze Team.","en":"As the boss, he bears responsibility for the whole team.","ru":"Как начальник, он несёт ответственность за всю команду.","vi":"Là ông chủ, anh ấy chịu trách nhiệm cho toàn bộ đội.","fa":"به عنوان رئیس، او مسئول کل تیم است."},{"de":"Niemand wollte die Verantwortung für den Fehler übernehmen.","en":"Nobody wanted to take responsibility for the mistake.","ru":"Никто не хотел брать на себя ответственность за ошибку.","vi":"Không ai muốn chịu trách nhiệm về sai lầm.","fa":"هیچ کس نمی خواست مسئولیت این اشتباه را بپذیرد."}]},{"word":"die Verantwortungsbereitschaft","en":"willingness to take responsibility","ru":"готовность брать на себя ответственность","vi":"sẵn sàng chịu trách nhiệm","fa":"تمایل به مسئولیت پذیری","examples":[{"de":"Der Job verlangt ein hohes Maß an Verantwortungsbereitschaft.","en":"The job demands a high degree of willingness to take responsibility.","ru":"Работа требует высокой готовности брать на себя ответственность.","vi":"Công việc đòi hỏi tinh thần trách nhiệm cao.","fa":"این شغل به مسئولیت پذیری بالایی نیاز دارد."},{"de":"Ihre Verantwortungsbereitschaft hat den Chef beeindruckt.","en":"Her willingness to take responsibility impressed the boss.","ru":"Её готовность брать ответственность впечатлила начальника.","vi":"Sự sẵn sàng chịu trách nhiệm của cô đã gây ấn tượng với ông chủ.","fa":"تمایل او به قبول مسئولیت رئیس را تحت تأثیر قرار داد."},{"de":"Verantwortungsbereitschaft ist im Team sehr gefragt.","en":"Willingness to take responsibility is much sought after in the team.","ru":"Готовность брать на себя ответственность очень ценится в команде.","vi":"Sự sẵn sàng chịu trách nhiệm là rất quan trọng trong nhóm.","fa":"تمایل به قبول مسئولیت در تیم بسیار مهم است."}]},{"word":"verarbeiten","en":"to process","ru":"обрабатывать","vi":"quá trình","fa":"فرآیند","examples":[{"de":"Der Computer kann diese Daten in Sekunden verarbeiten.","en":"The computer can process this data in seconds.","ru":"Компьютер может обработать эти данные за секунды.","vi":"Máy tính có thể xử lý dữ liệu này trong vài giây.","fa":"کامپیوتر می تواند این داده ها را در چند ثانیه پردازش کند."},{"de":"Bevor wir die Zahlen verarbeiten, müssen wir sie prüfen.","en":"Before we process the figures, we have to check them.","ru":"Прежде чем обрабатывать цифры, мы должны их проверить.","vi":"Trước khi xử lý các con số, chúng ta phải kiểm tra chúng.","fa":"قبل از پردازش اعداد، باید آنها را بررسی کنیم."},{"de":"Das Programm verarbeitet täglich Millionen von Anfragen.","en":"The program processes millions of requests every day.","ru":"Программа обрабатывает миллионы запросов ежедневно.","vi":"Chương trình xử lý hàng triệu yêu cầu mỗi ngày.","fa":"این برنامه روزانه میلیون ها درخواست را پردازش می کند."}]},{"word":"verbessern","en":"to improve; to correct","ru":"улучшать; исправлять","vi":"cải thiện","fa":"بهبود بخشد","examples":[{"de":"Ich möchte mein Deutsch verbessern.","en":"I want to improve my German.","ru":"Я хочу улучшить свой немецкий.","vi":"Tôi muốn cải thiện tiếng Đức của mình.","fa":"من می خواهم آلمانی ام را بهتر کنم."},{"de":"Die Firma will den Service verbessern.","en":"The company wants to improve its service.","ru":"Фирма хочет улучшить сервис.","vi":"Công ty muốn cải thiện dịch vụ.","fa":"این شرکت می خواهد خدمات را بهبود بخشد."},{"de":"Der Lehrer verbesserte meine Fehler im Text.","en":"The teacher corrected my mistakes in the text.","ru":"Учитель исправил мои ошибки в тексте.","vi":"Giáo viên đã sửa lỗi sai của tôi trong văn bản.","fa":"معلم اشتباهات من را در متن تصحیح کرد."}]},{"word":"die Verbesserung","en":"improvement","ru":"улучшение","vi":"sự cải tiến","fa":"بهبود","examples":[{"de":"Wir arbeiten an einer Verbesserung des Programms.","en":"We're working on an improvement to the program.","ru":"Мы работаем над улучшением программы.","vi":"Chúng tôi đang nỗ lực cải thiện chương trình.","fa":"ما روی بهبود برنامه کار می کنیم."},{"de":"Es gab eine deutliche Verbesserung der Lage.","en":"There was a clear improvement in the situation.","ru":"Произошло заметное улучшение ситуации.","vi":"Có một sự cải thiện đáng kể trong tình hình.","fa":"بهبود قابل توجهی در وضعیت وجود داشت."},{"de":"Vielen Dank für Ihre Vorschläge zur Verbesserung.","en":"Thank you for your suggestions for improvement.","ru":"Большое спасибо за ваши предложения по улучшению.","vi":"Cảm ơn bạn đã đề xuất cải tiến.","fa":"ممنون از پیشنهادات شما برای بهبود"}]},{"word":"verbieten","en":"to forbid, prohibit","ru":"запрещать","vi":"lệnh cấm","fa":"ممنوع کردن","examples":[{"de":"Meine Eltern haben mir das Rauchen verboten.","en":"My parents forbade me to smoke.","ru":"Мои родители запретили мне курить.","vi":"Bố mẹ tôi cấm tôi hút thuốc.","fa":"پدر و مادرم من را از کشیدن سیگار منع کردند."},{"de":"Hier ist das Parken verboten.","en":"Parking is forbidden here.","ru":"Здесь парковка запрещена.","vi":"Bãi đậu xe bị cấm ở đây.","fa":"پارک کردن در اینجا ممنوع است."}]},{"word":"verbinden","en":"to connect, link","ru":"соединять","vi":"kết nối","fa":"اتصال","examples":[{"de":"Die Brücke verbindet die beiden Stadtteile.","en":"The bridge connects the two city districts.","ru":"Мост соединяет два района города.","vi":"Cây cầu nối hai phần của thành phố.","fa":"این پل دو قسمت شهر را به هم متصل می کند."},{"de":"Können Sie mich bitte mit Herrn Müller verbinden?","en":"Could you please connect me to Mr. Müller?","ru":"Не могли бы вы соединить меня с господином Мюллером?","vi":"Bạn có thể vui lòng kết nối tôi với ông Müller được không?","fa":"میشه لطفا من رو با آقای مولر وصل کنید؟"}]},{"word":"die Verbindung","en":"connection","ru":"соединение, подключение","vi":"sự kết nối","fa":"اتصال","examples":[{"de":"Die Verbindung zum Internet ist gerade sehr langsam.","en":"The connection to the internet is very slow right now.","ru":"Соединение с интернетом сейчас очень медленное.","vi":"Hiện tại kết nối internet rất chậm.","fa":"اتصال به اینترنت در حال حاضر بسیار کند است."},{"de":"Ohne Verbindung kannst du die Datei nicht herunterladen.","en":"Without a connection you can't download the file.","ru":"Без соединения ты не можешь скачать файл.","vi":"Nếu không có kết nối, bạn không thể tải tập tin xuống.","fa":"بدون اتصال نمی توانید فایل را دانلود کنید."},{"de":"Die Verbindung ist plötzlich abgebrochen.","en":"The connection suddenly dropped.","ru":"Соединение внезапно оборвалось.","vi":"Kết nối bị mất đột ngột.","fa":"اتصال ناگهان قطع می شود."}]},{"word":"das Verbot","en":"ban, prohibition","ru":"запрет","vi":"lệnh cấm","fa":"ممنوعیت","examples":[{"de":"In diesem Gebäude gilt ein striktes Rauchverbot, also ein Verbot zu rauchen.","en":"In this building there is a strict smoking ban, that is, a ban on smoking.","ru":"В этом здании действует строгий запрет на курение.","vi":"Có lệnh cấm hút thuốc nghiêm ngặt trong tòa nhà này, tức là cấm hút thuốc.","fa":"ممنوعیت شدید سیگار در این ساختمان وجود دارد، یعنی ممنوعیت استعمال دخانیات."},{"de":"Das Verbot von Plastiktüten soll der Umwelt helfen.","en":"The ban on plastic bags is meant to help the environment.","ru":"Запрет на пластиковые пакеты призван помочь окружающей среде.","vi":"Cấm túi nhựa sẽ giúp ích cho môi trường.","fa":"ممنوعیت کیسه های پلاستیکی باید به محیط زیست کمک کند."},{"de":"Trotz des Verbots sind viele Autos in die Innenstadt gefahren.","en":"Despite the ban, many cars drove into the city centre.","ru":"Несмотря на запрет, многие машины въезжали в центр города.","vi":"Bất chấp lệnh cấm, nhiều ô tô vẫn lao vào trung tâm thành phố.","fa":"با وجود ممنوعیت، بسیاری از خودروها به مرکز شهر رفتند."}]},{"word":"der Verbrauch","en":"consumption","ru":"потребление; расход","vi":"sự tiêu thụ","fa":"مصرف","examples":[{"de":"Dieses Auto hat einen niedrigen Verbrauch.","en":"This car has low fuel consumption.","ru":"У этой машины низкий расход топлива.","vi":"Chiếc xe này có mức tiêu thụ thấp.","fa":"این خودرو کم مصرف است."},{"de":"Wir versuchen, unseren Verbrauch von Strom zu senken.","en":"We are trying to reduce our electricity consumption.","ru":"Мы стараемся снизить потребление электроэнергии.","vi":"Chúng tôi đang cố gắng giảm mức tiêu thụ điện.","fa":"تلاش می کنیم مصرف برق را کاهش دهیم."}]},{"word":"verbrauchen","en":"to consume, use up","ru":"расходовать, потреблять","vi":"tiêu thụ","fa":"مصرف کنند","examples":[{"de":"Unser Auto verbraucht wenig Benzin.","en":"Our car uses little gasoline.","ru":"Наша машина потребляет мало бензина.","vi":"Xe của chúng tôi sử dụng ít xăng.","fa":"ماشین ما بنزین کمی مصرف می کند."},{"de":"Wir haben schon das ganze Wasser verbraucht.","en":"We've already used up all the water.","ru":"Мы уже израсходовали всю воду.","vi":"Chúng tôi đã sử dụng hết nước rồi.","fa":"ما قبلاً از تمام آب استفاده کرده ایم."}]},{"word":"der Verbraucher","en":"consumer","ru":"потребитель","vi":"người tiêu dùng","fa":"مصرف کننده","examples":[{"de":"Verbraucher achten immer mehr auf nachhaltige Produkte.","en":"Consumers pay more and more attention to sustainable products.","ru":"Потребители всё больше обращают внимание на устойчивые товары.","vi":"Người tiêu dùng ngày càng quan tâm nhiều hơn đến các sản phẩm bền vững.","fa":"مصرف کنندگان بیشتر و بیشتر به محصولات پایدار توجه می کنند."},{"de":"Der Verbraucher kann durch sein Kaufverhalten viel bewirken.","en":"The consumer can achieve a lot through their buying behaviour.","ru":"Потребитель своим покупательским поведением может многого добиться.","vi":"Người tiêu dùng có thể có tác động lớn thông qua hành vi mua hàng của họ.","fa":"مصرف کنندگان می توانند از طریق رفتار خرید خود تأثیر زیادی داشته باشند."},{"de":"Viele Verbraucher wissen nicht, woher ihr Strom kommt.","en":"Many consumers don't know where their electricity comes from.","ru":"Многие потребители не знают, откуда берётся их электричество.","vi":"Nhiều người tiêu dùng không biết nguồn điện của họ đến từ đâu.","fa":"بسیاری از مصرف کنندگان نمی دانند برق آنها از کجا می آید."}]},{"word":"der Verbrecher","en":"the criminal","ru":"преступник","vi":"tên tội phạm","fa":"جنایتکار","examples":[{"de":"Die Polizei hat den Verbrecher gefasst.","en":"The police caught the criminal.","ru":"Полиция поймала преступника.","vi":"Cảnh sát đã bắt được tội phạm.","fa":"پلیس جنایتکار را دستگیر کرد."},{"de":"Der Verbrecher wurde zu fünf Jahren Haft verurteilt.","en":"The criminal was sentenced to five years in prison.","ru":"Преступника приговорили к пяти годам заключения.","vi":"Tên tội phạm đã bị kết án năm năm tù.","fa":"مجرم به پنج سال زندان محکوم شد."}]},{"word":"die Verbrecherin","en":"criminal (female)","ru":"преступница (женщина)","vi":"tên tội phạm","fa":"جنایتکار","examples":[{"de":"Die Verbrecherin floh nach dem Überfall ins Ausland.","en":"The criminal fled abroad after the robbery.","ru":"После ограбления преступница бежала за границу.","vi":"Tên tội phạm đã trốn ra nước ngoài sau vụ tấn công.","fa":"جنایتکار پس از حمله به خارج از کشور گریخت."},{"de":"Vor Gericht zeigte die Verbrecherin keine Reue.","en":"In court the criminal showed no remorse.","ru":"В суде преступница не проявила раскаяния.","vi":"Tên tội phạm không tỏ ra hối hận trước tòa.","fa":"جنایتکار در دادگاه ابراز پشیمانی نکرد."},{"de":"Die gesuchte Verbrecherin wurde am Flughafen erkannt.","en":"The wanted criminal was recognised at the airport.","ru":"Разыскиваемую преступницу узнали в аэропорту.","vi":"Tên tội phạm bị truy nã đã được nhận dạng tại sân bay.","fa":"جنایتکار تحت تعقیب در فرودگاه شناسایی شد."}]},{"word":"verbrennen","en":"to burn, to burn up; to scald oneself","ru":"сжигать, сгорать; обжигаться","vi":"đốt cháy","fa":"سوختن","examples":[{"de":"Pass auf, dass du dir die Hand nicht verbrennst.","en":"Be careful not to burn your hand.","ru":"Осторожно, не обожги руку.","vi":"Hãy cẩn thận để không bị bỏng tay.","fa":"مراقب باش دستت نسوزد."},{"de":"Sie verbrannte die alten Briefe im Kamin.","en":"She burned the old letters in the fireplace.","ru":"Она сожгла старые письма в камине.","vi":"Cô đốt những lá thư cũ trong lò sưởi.","fa":"نامه های قدیمی را در شومینه سوزاند."},{"de":"Beim Sport verbrennt man viele Kalorien.","en":"You burn a lot of calories doing sport.","ru":"Занимаясь спортом, сжигаешь много калорий.","vi":"Khi tập thể dục, bạn đốt cháy rất nhiều calo.","fa":"وقتی ورزش می کنید کالری زیادی می سوزانید."}]},{"word":"die Verbrennung","en":"combustion, burning","ru":"сжигание, горение","vi":"sự đốt cháy","fa":"احتراق","examples":[{"de":"Bei der Verbrennung von Öl entstehen schädliche Gase.","en":"Harmful gases are produced during the combustion of oil.","ru":"При сжигании нефти образуются вредные газы.","vi":"Khi dầu bị đốt cháy sẽ sinh ra các khí độc hại.","fa":"هنگامی که نفت سوزانده می شود، گازهای مضر تولید می شود."},{"de":"Die Verbrennung von Kohle belastet die Luft stark.","en":"The burning of coal pollutes the air heavily.","ru":"Сжигание угля сильно загрязняет воздух.","vi":"Đốt than gây ô nhiễm không khí nặng nề.","fa":"سوزاندن زغال سنگ هوا را به شدت آلوده می کند."},{"de":"Statt der Verbrennung sollte mehr Müll wiederverwendet werden.","en":"Instead of incineration, more waste should be reused.","ru":"Вместо сжигания больше мусора следует использовать повторно.","vi":"Thay vì đốt, nên tái sử dụng nhiều chất thải hơn.","fa":"به جای سوزاندن، زباله های بیشتری باید دوباره استفاده شوند."}]},{"word":"verbringen","en":"to spend (time)","ru":"проводить (время)","vi":"chi tiêu","fa":"خرج کردن","examples":[{"de":"Wir haben den Urlaub am Meer verbracht.","en":"We spent the vacation at the sea.","ru":"Мы провели отпуск на море.","vi":"Chúng tôi đã trải qua kỳ nghỉ bên bờ biển.","fa":"تعطیلات را کنار دریا گذراندیم."},{"de":"Sie verbringt viel Zeit mit ihren Kindern.","en":"She spends a lot of time with her children.","ru":"Она проводит много времени со своими детьми.","vi":"Cô dành nhiều thời gian cho con cái.","fa":"او زمان زیادی را با فرزندانش می گذراند."}]},{"word":"der Verdacht","en":"the suspicion","ru":"подозрение","vi":"sự nghi ngờ","fa":"سوء ظن","examples":[{"de":"Die Polizei hat einen Verdacht gegen ihn.","en":"The police have a suspicion against him.","ru":"У полиции есть подозрение против него.","vi":"Cảnh sát có những nghi ngờ chống lại anh ta.","fa":"پلیس به او مشکوک است."},{"de":"Es besteht der Verdacht, dass er gelogen hat.","en":"There is a suspicion that he lied.","ru":"Есть подозрение, что он солгал.","vi":"Có nghi ngờ rằng anh ta đã nói dối.","fa":"این شبهه وجود دارد که او دروغ گفته است."}]},{"word":"verdächtig","en":"suspicious; (as noun) suspect","ru":"подозрительный; (сущ.) подозреваемый","vi":"nghi ngờ","fa":"مشکوک","examples":[{"de":"Bei diesem Fall gibt es zwei Verdächtige.","en":"In this case there are two suspects.","ru":"В этом деле двое подозреваемых.","vi":"Có hai nghi phạm trong vụ án này.","fa":"در این پرونده دو مظنون وجود دارد."},{"de":"Der Verdächtige wurde am Bahnhof festgenommen.","en":"The suspect was arrested at the station.","ru":"Подозреваемого задержали на вокзале.","vi":"Nghi phạm đã bị bắt tại nhà ga xe lửa.","fa":"مظنون در ایستگاه قطار دستگیر شد."},{"de":"Sein Verhalten kam dem Polizisten verdächtig vor.","en":"His behaviour seemed suspicious to the police officer.","ru":"Его поведение показалось полицейскому подозрительным.","vi":"Viên cảnh sát nhận thấy hành vi của anh ta đáng ngờ.","fa":"افسر پلیس رفتار او را مشکوک دید."}]},{"word":"verdienen","en":"to earn","ru":"зарабатывать","vi":"kiếm tiền","fa":"کسب کنید","examples":[{"de":"Sie verdient sehr gut in ihrem neuen Job.","en":"She earns very well in her new job.","ru":"Она очень хорошо зарабатывает на новой работе.","vi":"Cô ấy kiếm được rất tốt trong công việc mới của mình.","fa":"او در شغل جدیدش درآمد بسیار خوبی دارد."},{"de":"Er verdient nicht genug, um eine Familie zu ernähren.","en":"He doesn't earn enough to support a family.","ru":"Он зарабатывает недостаточно, чтобы содержать семью.","vi":"Anh ấy không kiếm đủ tiền để nuôi sống gia đình.","fa":"او آنقدر درآمد ندارد که بتواند خانواده اش را تامین کند."}]},{"word":"der Verein","en":"the club, association","ru":"клуб, объединение","vi":"câu lạc bộ","fa":"باشگاه","examples":[{"de":"Ich bin Mitglied in einem Sportverein.","en":"I am a member of a sports club.","ru":"Я член спортивного клуба.","vi":"Tôi là thành viên của một câu lạc bộ thể thao.","fa":"من عضو یک باشگاه ورزشی هستم."},{"de":"Der Verein organisiert jedes Jahr ein großes Fest.","en":"The club organizes a big festival every year.","ru":"Клуб каждый год организует большой праздник.","vi":"Câu lạc bộ tổ chức một lễ hội lớn hàng năm.","fa":"این باشگاه هر ساله یک جشنواره بزرگ برگزار می کند."}]},{"word":"vereinbaren","en":"to agree on, arrange","ru":"договариваться, согласовывать","vi":"đồng ý","fa":"موافق","examples":[{"de":"Wir haben einen Termin für nächste Woche vereinbart.","en":"We arranged an appointment for next week.","ru":"Мы договорились о встрече на следующую неделю.","vi":"Chúng tôi đã hẹn nhau vào tuần tới.","fa":"برای هفته آینده قرار گذاشتیم."},{"de":"Können wir einen anderen Preis vereinbaren?","en":"Can we agree on a different price?","ru":"Можем мы договориться о другой цене?","vi":"Chúng ta có thể thỏa thuận một mức giá khác được không?","fa":"آیا می توانیم روی قیمت متفاوتی به توافق برسیم؟"}]},{"word":"die Vereinbarung","en":"agreement, arrangement","ru":"договорённость, соглашение","vi":"thỏa thuận","fa":"توافقنامه","examples":[{"de":"Wir haben eine schriftliche Vereinbarung getroffen.","en":"We made a written agreement.","ru":"Мы заключили письменную договорённость.","vi":"Chúng tôi có một thỏa thuận bằng văn bản.","fa":"ما یک توافق نامه کتبی داریم."},{"de":"Laut Vereinbarung liefern Sie die Ware bis Freitag.","en":"According to the agreement, you will deliver the goods by Friday.","ru":"Согласно договорённости, вы поставите товар до пятницы.","vi":"Theo thỏa thuận, bạn giao hàng vào thứ Sáu.","fa":"طبق قرارداد، شما کالا را تا جمعه تحویل می دهید."},{"de":"Die beiden Firmen unterzeichneten eine neue Vereinbarung.","en":"The two companies signed a new agreement.","ru":"Две компании подписали новое соглашение.","vi":"Hai công ty đã ký một thỏa thuận mới.","fa":"دو شرکت قرارداد جدیدی امضا کردند."}]},{"word":"die Verfolgung","en":"persecution","ru":"преследование, гонения","vi":"cuộc đàn áp","fa":"the persecution","examples":[{"de":"Viele Menschen flohen vor der Verfolgung ins Ausland.","en":"Many people fled abroad to escape persecution.","ru":"Многие люди бежали за границу, спасаясь от преследования.","vi":"Nhiều người đã trốn ra nước ngoài để thoát khỏi sự đàn áp.","fa":"بسیاری از مردم برای فرار از آزار و اذیت به خارج از کشور گریختند."},{"de":"Die religiöse Verfolgung dauerte viele Jahre.","en":"The religious persecution lasted many years.","ru":"Религиозные гонения длились много лет.","vi":"Cuộc đàn áp tôn giáo kéo dài nhiều năm.","fa":"آزار و اذیت مذهبی سال ها ادامه داشت."},{"de":"Die Opfer der Verfolgung werden bis heute geehrt.","en":"The victims of the persecution are still honoured today.","ru":"Жертв преследования чтят и по сей день.","vi":"Các nạn nhân của cuộc đàn áp vẫn được vinh danh cho đến ngày nay.","fa":"قربانیان آزار و اذیت امروز نیز مورد تجلیل قرار می گیرند."}]},{"word":"die Vergangenheit","en":"the past","ru":"прошлое","vi":"quá khứ","fa":"گذشته","examples":[{"de":"In der Vergangenheit war das Leben hier viel schwerer.","en":"In the past, life here was much harder.","ru":"В прошлом жизнь здесь была намного тяжелее.","vi":"Ngày xưa cuộc sống ở đây khó khăn hơn nhiều.","fa":"در گذشته زندگی اینجا خیلی سخت تر بود."},{"de":"Er spricht selten über seine Vergangenheit.","en":"He rarely talks about his past.","ru":"Он редко говорит о своём прошлом.","vi":"Anh ấy hiếm khi nói về quá khứ của mình.","fa":"او به ندرت از گذشته خود صحبت می کند."}]},{"word":"die Vergangenheitsbewältigung","en":"coming to terms with the past","ru":"преодоление (осмысление) прошлого, работа с прошлым","vi":"chấp nhận quá khứ","fa":"کنار آمدن با گذشته","examples":[{"de":"Vergangenheitsbewältigung ist ein langer Prozess.","en":"Coming to terms with the past is a long process.","ru":"Преодоление прошлого — долгий процесс.","vi":"Chấp nhận quá khứ là một quá trình lâu dài.","fa":"کنار آمدن با گذشته فرآیندی طولانی است."},{"de":"Das Land arbeitet an seiner Vergangenheitsbewältigung.","en":"The country is working on coming to terms with its past.","ru":"Страна работает над осмыслением своего прошлого.","vi":"Đất nước này đang cố gắng chấp nhận quá khứ của mình.","fa":"این کشور در تلاش است تا با گذشته خود کنار بیاید."},{"de":"Vergangenheitsbewältigung braucht Offenheit.","en":"Coming to terms with the past requires openness.","ru":"Преодоление прошлого требует открытости.","vi":"Chấp nhận quá khứ đòi hỏi sự cởi mở.","fa":"کنار آمدن با گذشته نیاز به باز بودن دارد."}]},{"word":"vergeblich","en":"in vain, futile","ru":"напрасный, тщетный","vi":"vô ích","fa":"بیهوده","examples":[{"de":"Alle Versuche waren vergeblich.","en":"All attempts were in vain.","ru":"Все попытки были напрасны.","vi":"Mọi nỗ lực đều vô ích.","fa":"همه تلاش ها بی نتیجه بود."},{"de":"Wir haben vergeblich auf ihn gewartet.","en":"We waited for him in vain.","ru":"Мы напрасно ждали его.","vi":"Chúng tôi chờ đợi anh ấy trong vô vọng.","fa":"بیهوده منتظرش بودیم."}]},{"word":"vergessen","en":"to forget","ru":"забывать","vi":"bị lãng quên","fa":"فراموش شده","examples":[{"de":"Ich habe meinen Regenschirm zu Hause vergessen.","en":"I forgot my umbrella at home.","ru":"Я забыл дома свой зонт.","vi":"Tôi quên ô ở nhà.","fa":"چترم را در خانه فراموش کردم."},{"de":"Vergiss nicht, die Tür abzuschließen!","en":"Don't forget to lock the door!","ru":"Не забудь запереть дверь!","vi":"Đừng quên khóa cửa!","fa":"فراموش نکنید که در را قفل کنید!"}]},{"word":"der Vergleich","en":"comparison","ru":"сравнение","vi":"sự so sánh","fa":"مقایسه","examples":[{"de":"Im Vergleich zu letztem Jahr ist alles teurer geworden.","en":"Compared to last year, everything has become more expensive.","ru":"По сравнению с прошлым годом всё подорожало.","vi":"So với năm ngoái, mọi thứ đã trở nên đắt đỏ hơn.","fa":"نسبت به سال گذشته همه چیز گران شده است."},{"de":"Ein Vergleich der Preise lohnt sich vor dem Kauf.","en":"Comparing the prices is worthwhile before buying.","ru":"Перед покупкой стоит сравнить цены.","vi":"Thật đáng để so sánh giá trước khi mua.","fa":"ارزش مقایسه قیمت ها را قبل از خرید دارد."},{"de":"Der Vergleich zwischen den beiden Städten ist interessant.","en":"The comparison between the two cities is interesting.","ru":"Сравнение двух городов интересно.","vi":"Sự so sánh giữa hai thành phố thật thú vị.","fa":"مقایسه این دو شهر جالب است."}]},{"word":"vergleichbar","en":"comparable","ru":"сравнимый, сопоставимый","vi":"so sánh được","fa":"قابل مقایسه","examples":[{"de":"Die beiden Fälle sind kaum vergleichbar.","en":"The two cases are hardly comparable.","ru":"Эти два случая едва ли сравнимы.","vi":"Hai trường hợp khó có thể so sánh được.","fa":"این دو مورد به سختی قابل مقایسه هستند."},{"de":"Das Ergebnis ist mit dem letzten Jahr vergleichbar.","en":"The result is comparable to last year.","ru":"Результат сопоставим с прошлым годом.","vi":"Kết quả này có thể so sánh với năm ngoái.","fa":"نتیجه قابل مقایسه با سال گذشته است."},{"de":"Es gibt nichts Vergleichbares auf dem Markt.","en":"There's nothing comparable on the market.","ru":"На рынке нет ничего сравнимого.","vi":"Không có gì có thể so sánh được trên thị trường.","fa":"هیچ چیز قابل مقایسه در بازار نیست."}]},{"word":"vergleichen","en":"to compare","ru":"сравнивать","vi":"so sánh","fa":"مقایسه کنید","examples":[{"de":"Man kann die beiden Angebote nicht direkt vergleichen.","en":"You can't directly compare the two offers.","ru":"Нельзя напрямую сравнивать эти два предложения.","vi":"Bạn không thể so sánh trực tiếp hai ưu đãi.","fa":"شما نمی توانید این دو پیشنهاد را مستقیماً مقایسه کنید."},{"de":"Vergleich die Preise, bevor du etwas kaufst.","en":"Compare the prices before you buy something.","ru":"Сравни цены, прежде чем что-то покупать.","vi":"So sánh giá trước khi bạn mua bất cứ điều gì.","fa":"قبل از خرید هر چیزی قیمت ها را مقایسه کنید."}]},{"word":"verglichen","en":"compared (to/with); past participle of vergleichen","ru":"по сравнению (с чем-либо); причастие от vergleichen","vi":"so sánh","fa":"مقایسه کرد","examples":[{"de":"Verglichen mit gestern ist es heute viel kälter.","en":"Compared to yesterday it's much colder today.","ru":"По сравнению со вчерашним днём сегодня намного холоднее.","vi":"So với hôm qua thì hôm nay trời lạnh hơn nhiều.","fa":"در مقایسه با دیروز، امروز بسیار سردتر است."},{"de":"Die Preise sind hoch, verglichen mit dem Vorjahr.","en":"Prices are high compared with last year.","ru":"Цены высоки по сравнению с прошлым годом.","vi":"Giá cao hơn so với năm ngoái.","fa":"قیمت ها نسبت به پارسال بالاست."},{"de":"Ich habe die beiden Angebote miteinander verglichen.","en":"I compared the two offers with each other.","ru":"Я сравнил оба предложения между собой.","vi":"Tôi đã so sánh hai lời đề nghị.","fa":"من این دو پیشنهاد را مقایسه کردم."}]},{"word":"das Vergnügen","en":"pleasure, enjoyment","ru":"удовольствие, наслаждение","vi":"niềm vui","fa":"لذت","examples":[{"de":"Es war mir ein großes Vergnügen, Sie kennenzulernen.","en":"It was a great pleasure to meet you.","ru":"Было большим удовольствием познакомиться с вами.","vi":"Rất vui được gặp bạn.","fa":"از آشنایی با شما بسیار خوشحال شدم."},{"de":"Sie reist nicht aus geschäftlichen Gründen, sondern zum Vergnügen.","en":"She isn't travelling for business reasons, but for pleasure.","ru":"Она едет не по делам, а ради удовольствия.","vi":"Cô ấy đi du lịch không phải vì công việc mà vì niềm vui.","fa":"او نه برای تجارت بلکه برای تفریح ​​سفر می کند."},{"de":"Mit Vergnügen helfe ich dir beim Umzug.","en":"I'll gladly help you with the move.","ru":"Я с удовольствием помогу тебе с переездом.","vi":"Tôi sẽ sẵn lòng giúp bạn di chuyển.","fa":"من خوشحال می شوم به شما کمک کنم تا حرکت کنید."}]},{"word":"vergnügt","en":"cheerful, merry, in good spirits","ru":"весёлый, довольный, в хорошем настроении","vi":"hạnh phúc","fa":"خوشحال","examples":[{"de":"Die Gäste waren vergnügt und lachten viel.","en":"The guests were cheerful and laughed a lot.","ru":"Гости были весёлыми и много смеялись.","vi":"Khách rất vui và cười rất nhiều.","fa":"مهمانان خوشحال شدند و بسیار خندیدند."},{"de":"Er pfiff vergnügt vor sich hin.","en":"He whistled merrily to himself.","ru":"Он весело насвистывал себе под нос.","vi":"Anh vui vẻ huýt sáo một mình.","fa":"با خوشحالی برای خودش سوت زد."},{"de":"Wir verbrachten einen vergnügten Abend zusammen.","en":"We spent a cheerful evening together.","ru":"Мы весело провели вечер вместе.","vi":"Chúng tôi đã cùng nhau trải qua một buổi tối vui vẻ.","fa":"یک عصر شاد را با هم گذراندیم."}]},{"word":"vergrößern","en":"to enlarge, to increase","ru":"увеличивать","vi":"phóng to","fa":"بزرگ کردن","examples":[{"de":"Der Fotograf möchte das Bild vergrößern lassen.","en":"The photographer wants to have the picture enlarged.","ru":"Фотограф хочет увеличить фотографию.","vi":"Nhiếp ảnh gia muốn hình ảnh được phóng to.","fa":"عکاس می خواهد تصویر بزرگ شود."},{"de":"Die Firma plant, ihre Produktion zu vergrößern.","en":"The company plans to increase its production.","ru":"Компания планирует увеличить производство.","vi":"Công ty có kế hoạch mở rộng sản xuất.","fa":"این شرکت قصد دارد تولید خود را گسترش دهد."}]},{"word":"verhaften","en":"to arrest","ru":"арестовывать","vi":"bắt giữ","fa":"دستگیری","examples":[{"de":"Die Polizei hat den Dieb verhaftet.","en":"The police arrested the thief.","ru":"Полиция арестовала вора.","vi":"Cảnh sát đã bắt giữ tên trộm.","fa":"پلیس سارق را دستگیر کرد."},{"de":"Er wurde wegen Betrugs verhaftet.","en":"He was arrested for fraud.","ru":"Его арестовали за мошенничество.","vi":"Anh ta bị bắt vì tội lừa đảo.","fa":"به جرم کلاهبرداری دستگیر شد."}]},{"word":"das Verhalten","en":"behaviour","ru":"поведение","vi":"hành vi","fa":"رفتار","examples":[{"de":"Sein Verhalten in der Gruppe war freundlich.","en":"His behaviour in the group was friendly.","ru":"Его поведение в группе было дружелюбным.","vi":"Cách cư xử của anh ấy trong nhóm rất thân thiện.","fa":"رفتارش در جمع دوستانه بود."},{"de":"Soziologen untersuchen das Verhalten von Menschen.","en":"Sociologists study people's behaviour.","ru":"Социологи изучают поведение людей.","vi":"Các nhà xã hội học nghiên cứu hành vi của con người.","fa":"جامعه شناسان رفتار افراد را مطالعه می کنند."},{"de":"Unser Verhalten wird stark von der Umgebung geprägt.","en":"Our behaviour is strongly shaped by our surroundings.","ru":"На наше поведение сильно влияет окружение.","vi":"Hành vi của chúng ta bị ảnh hưởng mạnh mẽ bởi môi trường của chúng ta.","fa":"رفتار ما به شدت تحت تأثیر محیط ما است."}]},{"word":"das Verhältnis","en":"relationship; ratio","ru":"отношение; соотношение","vi":"mối quan hệ","fa":"رابطه","examples":[{"de":"Sie hat ein gutes Verhältnis zu ihren Eltern.","en":"She has a good relationship with her parents.","ru":"У неё хорошие отношения с родителями.","vi":"Cô ấy có mối quan hệ tốt với bố mẹ mình.","fa":"او رابطه خوبی با پدر و مادرش دارد."},{"de":"Das Verhältnis von Preis und Leistung stimmt hier nicht.","en":"The price-to-performance ratio isn't right here.","ru":"Соотношение цены и качества здесь не соответствует.","vi":"Mối quan hệ giữa giá cả và hiệu suất không ổn ở đây.","fa":"رابطه بین قیمت و عملکرد در اینجا درست نیست."}]},{"word":"die Verhandlung","en":"negotiation","ru":"переговоры; судебное разбирательство","vi":"cuộc đàm phán","fa":"مذاکره","examples":[{"de":"Die Verhandlungen zwischen den Ländern waren schwierig.","en":"The negotiations between the countries were difficult.","ru":"Переговоры между странами были трудными.","vi":"Các cuộc đàm phán giữa các nước gặp nhiều khó khăn.","fa":"مذاکرات بین کشورها دشوار بود."},{"de":"Nach langen Verhandlungen kam es zu einer Einigung.","en":"After long negotiations an agreement was reached.","ru":"После долгих переговоров пришли к соглашению.","vi":"Sau một thời gian dài đàm phán, một thỏa thuận đã đạt được.","fa":"پس از مذاکرات طولانی، توافق حاصل شد."},{"de":"Die Verhandlung über den Frieden begann gestern.","en":"The negotiation about peace began yesterday.","ru":"Переговоры о мире начались вчера.","vi":"Các cuộc đàm phán hòa bình đã bắt đầu ngày hôm qua.","fa":"مذاکرات صلح دیروز آغاز شد."}]},{"word":"verheiratet","en":"married","ru":"женатый / замужняя","vi":"kết hôn","fa":"متاهل","examples":[{"de":"Meine Schwester ist seit fünf Jahren verheiratet.","en":"My sister has been married for five years.","ru":"Моя сестра замужем уже пять лет.","vi":"Chị gái tôi đã lấy chồng được năm năm.","fa":"خواهر من پنج سال است که ازدواج کرده است."},{"de":"Sind Sie verheiratet oder ledig?","en":"Are you married or single?","ru":"Вы женаты/замужем или холосты/не замужем?","vi":"Bạn đang độc thân hay đã kết hôn?","fa":"متاهل هستی یا مجرد؟"}]},{"word":"verhindern","en":"to prevent","ru":"предотвращать","vi":"ngăn chặn","fa":"جلوگیری کند","examples":[{"de":"Wir konnten den Unfall leider nicht verhindern.","en":"Unfortunately, we couldn't prevent the accident.","ru":"К сожалению, мы не смогли предотвратить аварию.","vi":"Thật không may, chúng tôi đã không thể ngăn chặn vụ tai nạn.","fa":"متاسفانه نتوانستیم از وقوع حادثه جلوگیری کنیم."},{"de":"Regelmäßiges Händewaschen kann Infektionen verhindern.","en":"Regular handwashing can prevent infections.","ru":"Регулярное мытьё рук может предотвратить инфекции.","vi":"Rửa tay thường xuyên có thể ngăn ngừa nhiễm trùng.","fa":"شستن مرتب دست ها می تواند از عفونت جلوگیری کند."}]},{"word":"verkaufen","en":"to sell","ru":"продавать","vi":"bán","fa":"فروش","examples":[{"de":"Er will sein altes Auto verkaufen.","en":"He wants to sell his old car.","ru":"Он хочет продать свою старую машину.","vi":"Anh ấy muốn bán chiếc xe cũ của mình.","fa":"او می خواهد ماشین قدیمی خود را بفروشد."},{"de":"Im Laden werden frisches Obst und Gemüse verkauft.","en":"Fresh fruit and vegetables are sold in the shop.","ru":"В магазине продают свежие фрукты и овощи.","vi":"Trái cây và rau quả tươi được bán trong cửa hàng.","fa":"میوه و سبزیجات تازه در مغازه به فروش می رسد."}]},{"word":"der Verkäufer","en":"salesman, shop assistant","ru":"продавец","vi":"người bán","fa":"فروشنده","examples":[{"de":"Der Verkäufer half mir bei der Auswahl der Schuhe.","en":"The salesman helped me choose the shoes.","ru":"Продавец помог мне выбрать обувь.","vi":"Người bán đã giúp tôi chọn giày.","fa":"فروشنده به من در انتخاب کفش کمک کرد."},{"de":"Der Verkäufer im Elektronikladen war sehr freundlich.","en":"The salesman in the electronics store was very friendly.","ru":"Продавец в магазине электроники был очень дружелюбным.","vi":"Nhân viên bán hàng ở cửa hàng điện máy rất thân thiện.","fa":"فروشنده در فروشگاه لوازم الکترونیکی بسیار خوش برخورد بود."}]},{"word":"die Verkäuferin","en":"shop assistant, saleswoman","ru":"продавщица","vi":"cô bán hàng","fa":"زن فروشنده","examples":[{"de":"Die Verkäuferin hat mir bei der Auswahl geholfen.","en":"The shop assistant helped me with the choice.","ru":"Продавщица помогла мне с выбором.","vi":"Cô bán hàng giúp tôi lựa chọn.","fa":"فروشنده به من در انتخاب کمک کرد."},{"de":"Meine Schwester arbeitet als Verkäuferin in einer Bäckerei.","en":"My sister works as a shop assistant in a bakery.","ru":"Моя сестра работает продавщицей в пекарне.","vi":"Em gái tôi làm nhân viên bán hàng ở một tiệm bánh.","fa":"خواهرم به عنوان فروشنده در یک نانوایی کار می کند."},{"de":"Die Verkäuferin war sehr freundlich und geduldig.","en":"The saleswoman was very friendly and patient.","ru":"Продавщица была очень приветливой и терпеливой.","vi":"Cô bán hàng rất thân thiện và kiên nhẫn.","fa":"خانم فروشنده بسیار صبور و صبور بود."}]},{"word":"der Verkehr","en":"traffic","ru":"движение, транспорт","vi":"giao thông","fa":"ترافیک","examples":[{"de":"Der Verkehr in der Innenstadt ist heute sehr stark.","en":"Traffic in the city center is very heavy today.","ru":"Движение в центре города сегодня очень плотное.","vi":"Giao thông ở trung tâm thành phố ngày nay rất đông đúc.","fa":"امروز ترافیک در مرکز شهر بسیار سنگین است."},{"de":"Wegen des Unfalls kam es zu einem Stau im Verkehr.","en":"Because of the accident there was a traffic jam.","ru":"Из-за аварии образовалась пробка в движении.","vi":"Vụ tai nạn khiến giao thông ùn tắc.","fa":"این تصادف باعث ایجاد ترافیک شد."}]},{"word":"das Verkehrsmittel","en":"means of transport","ru":"транспортное средство, вид транспорта","vi":"phương tiện vận tải","fa":"وسیله حمل و نقل","examples":[{"de":"Welches Verkehrsmittel nimmst du zur Arbeit?","en":"Which means of transport do you take to work?","ru":"Каким транспортом ты добираешься на работу?","vi":"Bạn đi làm bằng phương tiện gì?","fa":"با چه وسیله حمل و نقلی سر کار می روید؟"},{"de":"Öffentliche Verkehrsmittel sind oft günstiger als das Auto.","en":"Public means of transport are often cheaper than the car.","ru":"Общественный транспорт часто дешевле машины.","vi":"Phương tiện công cộng thường rẻ hơn ô tô.","fa":"حمل و نقل عمومی اغلب ارزان تر از ماشین است."},{"de":"In der Stadt benutze ich am liebsten umweltfreundliche Verkehrsmittel.","en":"In the city I prefer to use environmentally friendly means of transport.","ru":"В городе я предпочитаю экологичный транспорт.","vi":"Tôi thích sử dụng các phương tiện giao thông thân thiện với môi trường trong thành phố hơn.","fa":"من ترجیح می دهم از وسایل حمل و نقل سازگار با محیط زیست در شهر استفاده کنم."}]},{"word":"die Verkehrswende","en":"transport transition (shift to greener transport)","ru":"транспортная трансформация (переход к экологичному транспорту)","vi":"quá trình chuyển đổi vận tải","fa":"انتقال حمل و نقل","examples":[{"de":"Die Verkehrswende soll weg vom Auto und hin zu Bus und Bahn führen.","en":"The transport transition is meant to lead away from the car and towards buses and trains.","ru":"Транспортная трансформация должна увести от машины к автобусу и поезду.","vi":"Quá trình chuyển đổi giao thông nên chuyển từ ô tô sang xe buýt và tàu hỏa.","fa":"انتقال حمل و نقل باید از اتومبیل ها دور شود و به اتوبوس ها و قطارها برسد."},{"de":"Ohne eine echte Verkehrswende erreichen wir die Klimaziele nicht.","en":"Without a real transport transition we won't reach the climate targets.","ru":"Без настоящей транспортной трансформации мы не достигнем климатических целей.","vi":"Nếu không có sự chuyển đổi giao thông thực sự, chúng ta sẽ không đạt được các mục tiêu về khí hậu.","fa":"بدون انتقال واقعی حمل و نقل، ما به اهداف آب و هوایی خود نخواهیم رسید."},{"de":"Viele Städte investieren in die Verkehrswende.","en":"Many cities are investing in the transport transition.","ru":"Многие города инвестируют в транспортную трансформацию.","vi":"Nhiều thành phố đang đầu tư vào quá trình chuyển đổi giao thông.","fa":"بسیاری از شهرها در حال سرمایه گذاری در انتقال حمل و نقل هستند."}]},{"word":"das Verkehrszeichen","en":"traffic sign","ru":"дорожный знак","vi":"biển báo giao thông","fa":"علامت راهنمایی و رانندگی","examples":[{"de":"Beachte immer die Verkehrszeichen auf der Straße.","en":"Always pay attention to the traffic signs on the road.","ru":"Всегда обращай внимание на дорожные знаки.","vi":"Luôn chú ý đến các biển báo giao thông trên đường.","fa":"همیشه به علائم راهنمایی و رانندگی در جاده توجه کنید."},{"de":"Dieses Verkehrszeichen bedeutet Vorfahrt gewähren.","en":"This traffic sign means yield.","ru":"Этот дорожный знак означает «уступи дорогу».","vi":"Biển báo giao thông này có nghĩa là nhường đường.","fa":"این علامت راهنمایی و رانندگی به معنای راه دادن است."}]},{"word":"der Verlag","en":"publishing house, publisher","ru":"издательство","vi":"nhà xuất bản","fa":"ناشر","examples":[{"de":"Das Buch erscheint in einem bekannten Verlag.","en":"The book is being published by a well-known publisher.","ru":"Книга выходит в известном издательстве.","vi":"Sách được xuất bản bởi một nhà xuất bản nổi tiếng.","fa":"این کتاب توسط یک ناشر معروف منتشر شده است."},{"de":"Sie arbeitet als Lektorin bei einem Verlag.","en":"She works as an editor at a publishing house.","ru":"Она работает редактором в издательстве.","vi":"Cô ấy làm biên tập viên ở một nhà xuất bản.","fa":"او به عنوان ویراستار در یک انتشارات کار می کند."}]},{"word":"verlangen","en":"to demand, to require","ru":"требовать","vi":"nhu cầu","fa":"تقاضا","examples":[{"de":"Der Chef verlangt pünktliches Erscheinen.","en":"The boss demands punctual arrival.","ru":"Начальник требует приходить вовремя.","vi":"Sếp yêu cầu bạn phải đến đúng giờ.","fa":"رئیس از شما می خواهد که به موقع برسید."},{"de":"Diese Arbeit verlangt viel Geduld.","en":"This work requires a lot of patience.","ru":"Эта работа требует большого терпения.","vi":"Công việc này đòi hỏi rất nhiều sự kiên nhẫn.","fa":"این کار به صبر و حوصله زیادی نیاز دارد."}]},{"word":"verlängern","en":"to extend, to prolong","ru":"продлевать","vi":"mở rộng","fa":"تمدید کنید","examples":[{"de":"Ich möchte meinen Vertrag um ein Jahr verlängern.","en":"I would like to extend my contract by one year.","ru":"Я хотел бы продлить свой договор на год.","vi":"Tôi muốn gia hạn hợp đồng thêm một năm.","fa":"دوست دارم قراردادم را یک سال تمدید کنم."},{"de":"Kannst du bitte meinen Aufenthalt im Hotel verlängern?","en":"Could you please extend my stay at the hotel?","ru":"Не могли бы вы продлить моё проживание в отеле?","vi":"Bạn có thể vui lòng kéo dài thời gian lưu trú của tôi tại khách sạn được không?","fa":"لطفاً می توانید اقامت من در هتل را تمدید کنید؟"}]},{"word":"verlassen","en":"to leave","ru":"покидать","vi":"rời đi","fa":"ترک","examples":[{"de":"Er hat das Haus früh am Morgen verlassen.","en":"He left the house early in the morning.","ru":"Он покинул дом рано утром.","vi":"Anh rời khỏi nhà vào sáng sớm.","fa":"صبح زود از خانه بیرون رفت."},{"de":"Sie musste ihre Heimatstadt wegen der Arbeit verlassen.","en":"She had to leave her hometown because of work.","ru":"Ей пришлось покинуть родной город из-за работы.","vi":"Cô phải rời quê hương để đi làm.","fa":"او مجبور شد برای کار زادگاهش را ترک کند."}]},{"word":"der Verlauf","en":"course, progression","ru":"ход, течение, развитие","vi":"khóa học","fa":"دوره","examples":[{"de":"Im Verlauf des Tages wurde es wärmer.","en":"Over the course of the day it got warmer.","ru":"В течение дня стало теплее.","vi":"Càng ngày trời càng ấm hơn.","fa":"هر چه روز جلوتر می رفت گرمتر می شد."},{"de":"Der Verlauf der Geschichte überraschte alle.","en":"The course of the story surprised everyone.","ru":"Ход этой истории удивил всех.","vi":"Cách diễn biến câu chuyện khiến tất cả mọi người đều ngạc nhiên.","fa":"نحوه شکل گیری داستان همه را شگفت زده کرد."},{"de":"Der Verlauf der Krankheit war günstig.","en":"The progression of the illness was favourable.","ru":"Течение болезни было благоприятным.","vi":"Diễn biến của bệnh diễn biến thuận lợi.","fa":"سیر بیماری مطلوب بود."}]},{"word":"verlaufen","en":"to proceed, to go (a certain way); (sich) to get lost","ru":"проходить, протекать; (sich) заблудиться","vi":"chạy","fa":"اجرا کنید","examples":[{"de":"Die Prüfung ist gut verlaufen.","en":"The exam went well.","ru":"Экзамен прошёл хорошо.","vi":"Kỳ thi đã diễn ra tốt đẹp.","fa":"امتحان به خوبی پیش رفت."},{"de":"Wir haben uns im Wald verlaufen.","en":"We got lost in the forest.","ru":"Мы заблудились в лесу.","vi":"Chúng tôi bị lạc trong rừng.","fa":"ما در جنگل گم شدیم."},{"de":"Das Gespräch verlief ruhig und freundlich.","en":"The conversation proceeded calmly and amicably.","ru":"Разговор прошёл спокойно и дружелюбно.","vi":"Cuộc trò chuyện diễn ra bình tĩnh và thân thiện.","fa":"گفتگو آرام و دوستانه بود."}]},{"word":"verletzt","en":"injured; hurt","ru":"раненый, травмированный","vi":"bị thương","fa":"مجروح شد","examples":[{"de":"Nach dem Unfall gab es einen Verletzten.","en":"After the accident there was one injured person.","ru":"После аварии был один пострадавший.","vi":"Sau vụ tai nạn có 1 người bị thương.","fa":"در پی این تصادف یک نفر مجروح شد."},{"de":"Bei dem Sturz hat er sich am Knie verletzt.","en":"He injured his knee in the fall.","ru":"При падении он повредил колено.","vi":"Anh ấy bị thương ở đầu gối vào mùa thu.","fa":"او در سقوط زانویش آسیب دید."},{"de":"Der Verletzte wurde sofort ins Krankenhaus gebracht.","en":"The injured man was taken to hospital immediately.","ru":"Раненого сразу отвезли в больницу.","vi":"Người bị thương ngay lập tức được đưa tới bệnh viện.","fa":"مصدوم بلافاصله به بیمارستان منتقل شد."}]},{"word":"die Verletzung","en":"injury","ru":"травма, повреждение","vi":"vết thương","fa":"جراحت","examples":[{"de":"Der Spieler musste wegen einer Verletzung ausgewechselt werden.","en":"The player had to be substituted because of an injury.","ru":"Игрока пришлось заменить из-за травмы.","vi":"Cầu thủ này phải thay ra do chấn thương.","fa":"این بازیکن به دلیل مصدومیت مجبور به تعویض شد."},{"de":"Zum Glück war es nur eine leichte Verletzung.","en":"Fortunately it was only a minor injury.","ru":"К счастью, это была лишь лёгкая травма.","vi":"Rất may đó chỉ là một vết thương nhẹ.","fa":"خوشبختانه فقط یک مصدومیت جزئی بود."},{"de":"Die Verletzung am Knie heilt nur langsam.","en":"The injury to the knee is healing only slowly.","ru":"Травма колена заживает очень медленно.","vi":"Vết thương ở đầu gối đang dần lành lại.","fa":"آسیب زانو به آرامی در حال بهبود است."}]},{"word":"verliebt","en":"in love","ru":"влюблённый","vi":"đang yêu","fa":"عاشق","examples":[{"de":"In diesen Park gehen oft Verliebte.","en":"Couples in love often go to this park.","ru":"Влюблённые пары часто гуляют в этом парке.","vi":"Những người yêu nhau thường đến công viên này.","fa":"عاشقان اغلب به این پارک می روند."},{"de":"Sie ist zum ersten Mal richtig verliebt.","en":"She is properly in love for the first time.","ru":"Она по-настоящему влюблена впервые.","vi":"Cô ấy thực sự đang yêu lần đầu tiên.","fa":"او واقعاً برای اولین بار است که عاشق است."},{"de":"Die beiden sind seit dem Sommer ineinander verliebt.","en":"The two have been in love with each other since the summer.","ru":"Эти двое влюблены друг в друга с лета.","vi":"Hai người yêu nhau từ mùa hè.","fa":"این دو از تابستان عاشق یکدیگر بودند."}]},{"word":"verlieren","en":"to lose","ru":"терять; проигрывать","vi":"thua","fa":"از دست دادن","examples":[{"de":"Ich habe meinen Schlüssel verloren.","en":"I lost my key.","ru":"Я потерял свой ключ.","vi":"Tôi bị mất chìa khóa.","fa":"کلیدم را گم کردم"},{"de":"Unsere Mannschaft hat das Spiel knapp verloren.","en":"Our team narrowly lost the game.","ru":"Наша команда с небольшим отрывом проиграла игру.","vi":"Đội của chúng tôi suýt thua trận.","fa":"تیم ما بازی را با اختلاف کمی باخت."}]},{"word":"der Verlierer","en":"loser","ru":"проигравший, неудачник","vi":"kẻ thua cuộc","fa":"بازنده","examples":[{"de":"Beim Spiel gibt es immer einen Gewinner und einen Verlierer.","en":"In a game there is always a winner and a loser.","ru":"В игре всегда есть победитель и проигравший.","vi":"Trong trò chơi luôn có người thắng và người thua.","fa":"در بازی همیشه یک برنده و یک بازنده وجود دارد."},{"de":"Er ist ein schlechter Verlierer und wird schnell wütend.","en":"He is a bad loser and quickly gets angry.","ru":"Он плохо проигрывает и быстро злится.","vi":"Anh ấy là một kẻ thua cuộc và dễ nổi giận.","fa":"او یک بازنده سخت است و به راحتی عصبانی می شود."},{"de":"Die kleinen Geschäfte sind die Verlierer der Krise.","en":"The small shops are the losers of the crisis.","ru":"Маленькие магазины — проигравшие в кризисе.","vi":"Các doanh nghiệp nhỏ là những người thua cuộc trong cuộc khủng hoảng.","fa":"کسب و کارهای کوچک بازنده این بحران هستند."}]},{"word":"der Verlust","en":"loss","ru":"убыток, потеря","vi":"sự mất mát","fa":"the loss","examples":[{"de":"Das Geschäft hat im letzten Quartal einen Verlust gemacht.","en":"The business made a loss in the last quarter.","ru":"В прошлом квартале бизнес понёс убыток.","vi":"Việc kinh doanh đã thua lỗ trong quý trước.","fa":"کسب و کار در سه ماهه گذشته ضرر کرده است."},{"de":"Der Verkauf der Aktien brachte ihm einen großen Verlust.","en":"Selling the shares brought him a big loss.","ru":"Продажа акций принесла ему большой убыток.","vi":"Việc bán cổ phiếu đã mang lại cho anh một khoản lỗ lớn.","fa":"فروش سهام ضرر بزرگی برای او به همراه داشت."},{"de":"Die Firma versucht, den Verlust auszugleichen.","en":"The company is trying to make up for the loss.","ru":"Компания пытается возместить убыток.","vi":"Công ty đang cố gắng bù đắp sự mất mát.","fa":"این شرکت در تلاش است تا ضرر را جبران کند."}]},{"word":"vermeiden","en":"to avoid","ru":"избегать","vi":"tránh","fa":"اجتناب کنید","examples":[{"de":"Er versucht, Stress im Alltag zu vermeiden.","en":"He tries to avoid stress in everyday life.","ru":"Он старается избегать стресса в повседневной жизни.","vi":"Anh ấy cố gắng tránh căng thẳng trong cuộc sống hàng ngày.","fa":"او سعی می کند از استرس در زندگی روزمره خودداری کند."},{"de":"Um Fehler zu vermeiden, sollten Sie die Anleitung lesen.","en":"To avoid mistakes, you should read the instructions.","ru":"Чтобы избежать ошибок, вам следует прочитать инструкцию.","vi":"Để tránh sai sót, bạn nên đọc hướng dẫn.","fa":"برای جلوگیری از اشتباه، باید دستورالعمل ها را بخوانید."}]},{"word":"vermieten","en":"to rent out, to let","ru":"сдавать в аренду","vi":"thuê","fa":"اجاره","examples":[{"de":"Die Familie vermietet ein Zimmer an Studenten.","en":"The family rents out a room to students.","ru":"Семья сдаёт комнату студентам.","vi":"Gia đình cho sinh viên thuê phòng.","fa":"خانواده اتاقی را به دانش آموزان اجاره می دهند."},{"de":"Wir vermieten unsere Wohnung während des Urlaubs.","en":"We rent out our apartment during the vacation.","ru":"Мы сдаём свою квартиру во время отпуска.","vi":"Chúng tôi thuê căn hộ của mình khi đi nghỉ.","fa":"ما در تعطیلات آپارتمان خود را اجاره می دهیم."}]},{"word":"der Vermieter","en":"landlord","ru":"арендодатель; хозяин квартиры","vi":"chủ nhà","fa":"صاحبخانه","examples":[{"de":"Der Vermieter hat die Miete schon wieder erhöht.","en":"The landlord has raised the rent again.","ru":"Арендодатель снова поднял плату.","vi":"Chủ nhà lại tăng tiền thuê nhà rồi.","fa":"صاحبخانه قبلاً اجاره را دوباره افزایش داده است."},{"de":"Bei Problemen mit der Heizung rufe ich den Vermieter an.","en":"If there are problems with the heating, I call the landlord.","ru":"Если возникают проблемы с отоплением, я звоню арендодателю.","vi":"Nếu tôi gặp vấn đề với hệ thống sưởi, tôi sẽ gọi cho chủ nhà.","fa":"اگر با گرمایش مشکلی داشته باشم با صاحبخانه تماس می گیرم."}]},{"word":"die Vermietung","en":"rental, letting","ru":"сдача внаём, аренда (со стороны арендодателя)","vi":"tiền thuê","fa":"اجاره","examples":[{"de":"Die Vermietung von Ferienwohnungen ist hier sehr verbreitet.","en":"The rental of holiday flats is very common here.","ru":"Сдача внаём отпускных квартир здесь очень распространена.","vi":"Việc thuê căn hộ nghỉ dưỡng rất phổ biến ở đây.","fa":"اجاره آپارتمان های تعطیلات در اینجا بسیار رایج است."},{"de":"Für die Vermietung des Zimmers brauchen wir einen Vertrag.","en":"We need a contract for the letting of the room.","ru":"Для сдачи комнаты внаём нам нужен договор.","vi":"Chúng tôi cần hợp đồng thuê phòng.","fa":"برای اجاره اتاق نیازمند قرارداد هستیم."},{"de":"Die Firma ist auf die Vermietung von Autos spezialisiert.","en":"The company specialises in the rental of cars.","ru":"Компания специализируется на сдаче автомобилей в аренду.","vi":"Công ty chuyên cho thuê xe ô tô.","fa":"این شرکت در زمینه اجاره خودرو تخصص دارد."}]},{"word":"vermissen","en":"to miss (someone/something)","ru":"скучать (по кому-то), недосчитаться","vi":"nhớ","fa":"دلتنگ شدن","examples":[{"de":"Ich vermisse meine Familie sehr, seit ich im Ausland lebe.","en":"I miss my family a lot since I've been living abroad.","ru":"Я очень скучаю по семье с тех пор, как живу за границей.","vi":"Tôi nhớ gia đình tôi rất nhiều kể từ khi tôi sống ở nước ngoài.","fa":"از زمانی که خارج از کشور زندگی می کنم دلم برای خانواده ام بسیار تنگ شده است."},{"de":"Er hat erst später bemerkt, dass er seine Brille vermisst.","en":"He only noticed later that his glasses were missing.","ru":"Он заметил лишь позже, что не хватает его очков.","vi":"Sau này anh mới nhận ra rằng mình đã đánh mất chiếc kính.","fa":"او فقط بعداً متوجه شد که عینکش را از دست داده است."}]},{"word":"vermisst","en":"missing","ru":"пропавший (без вести)","vi":"bỏ lỡ","fa":"از دست رفته","examples":[{"de":"Die Polizei sucht eine Vermisste.","en":"The police are looking for a missing person.","ru":"Полиция ищет пропавшего человека.","vi":"Cảnh sát đang tìm kiếm một người mất tích.","fa":"پلیس به دنبال یک مفقود شده است."},{"de":"Der vermisste Junge wurde nach drei Tagen gefunden.","en":"The missing boy was found after three days.","ru":"Пропавшего мальчика нашли через три дня.","vi":"Cậu bé mất tích được tìm thấy sau ba ngày.","fa":"پسر گمشده پس از سه روز پیدا شد."},{"de":"Seit dem Sturm gilt ein Fischer als vermisst.","en":"A fisherman has been reported missing since the storm.","ru":"Со времени бури числится пропавшим один рыбак.","vi":"Một ngư dân đã mất tích sau cơn bão.","fa":"یک ماهیگیر از زمان طوفان مفقود شده است."}]},{"word":"die Vermittlung","en":"mediation; agency","ru":"посредничество; агентство","vi":"sự hòa giải","fa":"میانجیگری","examples":[{"de":"Durch die Vermittlung eines Freundes fand sie eine neue Stelle.","en":"Through a friend's mediation, she found a new job.","ru":"Благодаря посредничеству друга она нашла новую работу.","vi":"Nhờ sự giúp đỡ của một người bạn, cô đã tìm được một công việc mới.","fa":"او با کمک یکی از دوستانش شغل جدیدی پیدا کرد."},{"de":"Die Wohnung wurde über eine Vermittlung gefunden.","en":"The apartment was found through an agency.","ru":"Квартиру нашли через агентство.","vi":"Căn hộ được tìm thấy thông qua một cơ quan.","fa":"آپارتمان از طریق آژانس پیدا شد."}]},{"word":"vermuten","en":"to suspect, to assume","ru":"предполагать","vi":"nghi ngờ","fa":"مشکوک","examples":[{"de":"Ich vermute, dass er den Termin vergessen hat.","en":"I suspect that he forgot the appointment.","ru":"Я предполагаю, что он забыл о встрече.","vi":"Tôi nghi ngờ anh ấy đã quên cuộc hẹn.","fa":"من فکر می کنم او قرار ملاقات را فراموش کرده است."},{"de":"Die Polizei vermutet einen Zusammenhang zwischen den beiden Fällen.","en":"The police suspect a connection between the two cases.","ru":"Полиция предполагает связь между этими двумя делами.","vi":"Cảnh sát nghi ngờ có mối liên hệ giữa hai vụ án.","fa":"پلیس به ارتباط بین این دو مورد مشکوک است."}]},{"word":"vermutlich","en":"presumably, probably","ru":"предположительно, вероятно","vi":"có lẽ","fa":"احتمالا","examples":[{"de":"Er kommt vermutlich erst morgen zurück.","en":"He will presumably not be back until tomorrow.","ru":"Он предположительно вернётся только завтра.","vi":"Có lẽ anh ấy sẽ không về cho đến ngày mai.","fa":"احتمالا تا فردا برنمیگرده"},{"de":"Vermutlich hast du recht.","en":"You're probably right.","ru":"Вероятно, ты прав.","vi":"Có lẽ bạn đúng.","fa":"احتمالا حق با شماست."},{"de":"Das Konzert ist vermutlich schon ausverkauft.","en":"The concert is presumably already sold out.","ru":"Концерт, вероятно, уже распродан.","vi":"Buổi hòa nhạc có lẽ đã bán hết vé.","fa":"کنسرت احتمالا قبلاً فروخته شده است."}]},{"word":"die Vermutung","en":"hypothesis, assumption","ru":"предположение, гипотеза","vi":"phỏng đoán","fa":"حدس زدن","examples":[{"de":"Die Daten bestätigen unsere Vermutung.","en":"The data confirm our hypothesis.","ru":"Данные подтверждают наше предположение.","vi":"Dữ liệu xác nhận sự nghi ngờ của chúng tôi.","fa":"داده ها ظن ما را تایید می کند."},{"de":"Diese Vermutung müssen wir noch prüfen.","en":"We still have to test this assumption.","ru":"Это предположение нам ещё нужно проверить.","vi":"Chúng ta vẫn phải kiểm tra giả định này.","fa":"ما هنوز باید این فرض را آزمایش کنیم."},{"de":"Seine Vermutung war leider falsch.","en":"His assumption was unfortunately wrong.","ru":"Его предположение, к сожалению, было неверным.","vi":"Thật không may, giả định của anh đã sai.","fa":"متأسفانه فرض او اشتباه بود."}]},{"word":"vernünftig","en":"reasonable, sensible","ru":"разумный","vi":"hợp lý","fa":"منطقی","examples":[{"de":"Sei vernünftig und iss nicht so viel Süßes.","en":"Be sensible and don't eat so much candy.","ru":"Будь благоразумен и не ешь так много сладкого.","vi":"Hãy tỉnh táo và đừng ăn quá nhiều đồ ngọt.","fa":"عاقل باشید و اینقدر شیرینی نخورید."},{"de":"Das war eine vernünftige Entscheidung.","en":"That was a reasonable decision.","ru":"Это было разумное решение.","vi":"Đó là một quyết định sáng suốt.","fa":"این یک تصمیم معقول بود."}]},{"word":"veröffentlichen","en":"to publish","ru":"публиковать","vi":"xuất bản","fa":"منتشر کند","examples":[{"de":"Der Autor hat sein neues Buch veröffentlicht.","en":"The author published his new book.","ru":"Автор опубликовал свою новую книгу.","vi":"Tác giả đã xuất bản cuốn sách mới của mình.","fa":"این نویسنده کتاب جدید خود را منتشر کرده است."},{"de":"Die Fotos wurden im Internet veröffentlicht.","en":"The photos were published on the internet.","ru":"Фотографии были опубликованы в интернете.","vi":"Những bức ảnh được công bố trên Internet.","fa":"عکس ها در اینترنت منتشر شد."}]},{"word":"verpacken","en":"to pack, to wrap","ru":"упаковывать","vi":"gói","fa":"بسته","examples":[{"de":"Sie hat die Geschenke schön verpackt.","en":"She wrapped the presents nicely.","ru":"Она красиво упаковала подарки.","vi":"Cô gói quà thật đẹp.","fa":"او کادوها را به زیبایی پیچید."},{"de":"Die Ware wird sicher verpackt und verschickt.","en":"The goods are securely packed and shipped.","ru":"Товар надёжно упаковывают и отправляют.","vi":"Hàng hóa sẽ được đóng gói và vận chuyển an toàn.","fa":"کالا به صورت ایمن بسته بندی و ارسال می شود."}]},{"word":"verpassen","en":"to miss (a bus, opportunity, etc.)","ru":"упустить, опоздать на","vi":"lỡ (xe/cơ hội)","fa":"از دست دادن","examples":[{"de":"Ich habe den Bus verpasst und musste laufen.","en":"I missed the bus and had to walk.","ru":"Я опоздал на автобус и пришлось идти пешком.","vi":"Tôi bị lỡ xe buýt và phải đi bộ.","fa":"اتوبوس را از دست دادم و مجبور شدم پیاده بروم."},{"de":"Verpass nicht die Chance, dich zu bewerben!","en":"Don't miss the chance to apply!","ru":"Не упусти шанс подать заявку!","vi":"Đừng bỏ lỡ cơ hội ứng tuyển!","fa":"فرصت درخواست را از دست ندهید!"}]},{"word":"verpflegen","en":"to feed, to cater for","ru":"обеспечивать питанием","vi":"phục vụ","fa":"تهیه کردن","examples":[{"de":"Im Hotel werden die Gäste mit Halbpension verpflegt.","en":"At the hotel, guests are catered for with half board.","ru":"В отеле гостей обеспечивают питанием по системе полупансион.","vi":"Trong khách sạn, khách được cung cấp bao bữa sáng và tối.","fa":"در هتل به میهمانان با نیم تخته ارائه می شود."},{"de":"Die Helfer verpflegten die Flüchtlinge mit warmem Essen.","en":"The helpers provided the refugees with warm food.","ru":"Волонтёры обеспечивали беженцев горячей едой.","vi":"Những người giúp đỡ đã cung cấp thức ăn ấm cho người tị nạn.","fa":"امدادگران غذای گرم برای پناهندگان فراهم کردند."}]},{"word":"verpflichten","en":"to oblige, to commit","ru":"обязывать","vi":"bắt buộc","fa":"ملزم کردن","examples":[{"de":"Der Vertrag verpflichtet dich zu nichts.","en":"The contract obliges you to nothing.","ru":"Договор тебя ни к чему не обязывает.","vi":"Hợp đồng không bắt buộc bạn phải làm bất cứ điều gì.","fa":"قرارداد شما را ملزم به انجام کاری نمی کند."},{"de":"Ich fühle mich verpflichtet, ihr zu helfen.","en":"I feel obliged to help her.","ru":"Я чувствую себя обязанным ей помочь.","vi":"Tôi cảm thấy có nghĩa vụ phải giúp đỡ cô ấy.","fa":"من احساس وظیفه می کنم که به او کمک کنم."},{"de":"Das Unternehmen hat sich verpflichtet, umweltfreundlich zu arbeiten.","en":"The company has committed to working in an environmentally friendly way.","ru":"Компания обязалась работать экологично.","vi":"Công ty cam kết làm việc theo cách thân thiện với môi trường.","fa":"این شرکت متعهد است که به شیوه ای سازگار با محیط زیست کار کند."}]},{"word":"verpflichtet","en":"obliged, committed","ru":"обязан","vi":"bắt buộc","fa":"موظف است","examples":[{"de":"Als Mieter sind Sie verpflichtet, die Miete pünktlich zu zahlen.","en":"As a tenant, you are obliged to pay the rent on time.","ru":"Как арендатор вы обязаны вовремя платить арендную плату.","vi":"Là người thuê nhà, bạn có nghĩa vụ phải trả tiền thuê đúng hạn.","fa":"شما به عنوان مستاجر موظف هستید اجاره بها را به موقع پرداخت کنید."},{"de":"Ich fühle mich ihm gegenüber sehr verpflichtet.","en":"I feel very obligated to him.","ru":"Я чувствую себя очень обязанным перед ним.","vi":"Tôi cảm thấy có nghĩa vụ lớn lao với anh ấy.","fa":"نسبت به او احساس وظیفه بزرگی می کنم."}]},{"word":"verraten","en":"to betray; to reveal (a secret)","ru":"предавать; выдавать (тайну)","vi":"bị phản bội","fa":"خیانت کرده","examples":[{"de":"Er hat seinen besten Freund verraten.","en":"He betrayed his best friend.","ru":"Он предал своего лучшего друга.","vi":"Anh ta đã phản bội người bạn thân nhất của mình.","fa":"او به بهترین دوستش خیانت کرد."},{"de":"Verrate mir nicht, wie der Film endet!","en":"Don't tell me how the movie ends!","ru":"Не выдавай мне, чем закончится фильм!","vi":"Đừng nói cho tôi biết bộ phim kết thúc như thế nào!","fa":"به من نگو ​​فیلم چگونه تمام می شود!"}]},{"word":"verreisen","en":"to go on a trip, to travel away","ru":"уезжать в поездку","vi":"du lịch","fa":"سفر","examples":[{"de":"Wir verreisen dieses Jahr im Sommer nach Italien.","en":"We're going on a trip to Italy this summer.","ru":"В этом году летом мы уезжаем в Италию.","vi":"Chúng tôi đang đi du lịch đến Ý vào mùa hè này.","fa":"تابستان امسال به ایتالیا سفر می کنیم."},{"de":"Meine Nachbarn sind für zwei Wochen verreist.","en":"My neighbors have gone away for two weeks.","ru":"Мои соседи уехали на две недели.","vi":"Hàng xóm của tôi đã đi vắng được hai tuần.","fa":"همسایه های من دو هفته رفتند."}]},{"word":"verringern","en":"to reduce; to lessen","ru":"уменьшать; сокращать","vi":"giảm bớt","fa":"کاهش دهد","examples":[{"de":"Wir müssen unseren Müll deutlich verringern.","en":"We have to significantly reduce our waste.","ru":"Мы должны существенно сократить количество мусора.","vi":"Chúng ta cần giảm đáng kể chất thải của mình.","fa":"ما باید زباله های خود را به میزان قابل توجهی کاهش دهیم."},{"de":"Durch die neue Regel verringerte sich die Zahl der Unfälle.","en":"The new rule reduced the number of accidents.","ru":"Благодаря новому правилу число аварий уменьшилось.","vi":"Quy định mới làm giảm số vụ tai nạn.","fa":"قانون جدید تعداد تصادفات را کاهش داد."}]},{"word":"verrückt","en":"crazy","ru":"сумасшедший","vi":"điên rồ","fa":"دیوانه","examples":[{"de":"Das ist eine verrückte Idee, aber sie könnte funktionieren.","en":"That's a crazy idea, but it might work.","ru":"Это сумасшедшая идея, но она может сработать.","vi":"Đó là một ý tưởng điên rồ, nhưng nó có thể thành công.","fa":"این یک ایده دیوانه کننده است، اما می تواند کار کند."},{"de":"Er wird verrückt, wenn er im Stau steht.","en":"He goes crazy when he's stuck in traffic.","ru":"Он сходит с ума, когда стоит в пробке.","vi":"Anh ấy phát điên khi bị kẹt xe.","fa":"وقتی در ترافیک گیر می کند دیوانه می شود."}]},{"word":"die Versammlung","en":"assembly, meeting","ru":"собрание","vi":"hội đồng","fa":"مجمع","examples":[{"de":"Die Bewohner treffen sich zur jährlichen Versammlung.","en":"The residents meet for the annual assembly.","ru":"Жители собираются на ежегодное собрание.","vi":"Các cư dân họp mặt trong cuộc họp thường niên.","fa":"ساکنان برای جلسه سالانه گرد هم می آیند."},{"de":"In der Versammlung wurden wichtige Entscheidungen getroffen.","en":"Important decisions were made at the meeting.","ru":"На собрании были приняты важные решения.","vi":"Các quyết định quan trọng đã được đưa ra trong cuộc họp.","fa":"در این جلسه تصمیمات مهمی اتخاذ شد."}]},{"word":"der Versand","en":"dispatch, shipping","ru":"отправка, отгрузка (товара)","vi":"việc vận chuyển","fa":"حمل و نقل","examples":[{"de":"Der Versand der Ware erfolgt innerhalb von zwei Tagen.","en":"The dispatch of the goods takes place within two days.","ru":"Отправка товара происходит в течение двух дней.","vi":"Hàng hóa sẽ được gửi đi trong vòng hai ngày.","fa":"کالا تا دو روز دیگر ارسال خواهد شد."},{"de":"Beim Online-Kauf ist der Versand oft kostenlos.","en":"When buying online, shipping is often free.","ru":"При покупке онлайн доставка часто бесплатная.","vi":"Khi bạn mua hàng trực tuyến, vận chuyển thường miễn phí.","fa":"هنگام خرید آنلاین، حمل و نقل اغلب رایگان است."},{"de":"Der Versand ins Ausland dauert leider etwas länger.","en":"Shipping abroad unfortunately takes a bit longer.","ru":"Отправка за границу, к сожалению, занимает чуть больше времени.","vi":"Thật không may, vận chuyển ra nước ngoài mất nhiều thời gian hơn.","fa":"متاسفانه ارسال به خارج از کشور کمی بیشتر طول می کشد."}]},{"word":"die Versandkosten","en":"shipping costs (plural)","ru":"расходы на доставку (мн. ч.)","vi":"chi phí vận chuyển","fa":"هزینه های حمل و نقل","examples":[{"de":"Die Versandkosten betragen vier Euro pro Bestellung.","en":"The shipping costs amount to four euros per order.","ru":"Расходы на доставку составляют четыре евро за заказ.","vi":"Chi phí vận chuyển là bốn euro cho mỗi đơn hàng.","fa":"هزینه ارسال برای هر سفارش چهار یورو می باشد."},{"de":"Ab fünfzig Euro Bestellwert fallen keine Versandkosten an.","en":"From an order value of fifty euros there are no shipping costs.","ru":"При сумме заказа от пятидесяти евро расходов на доставку нет.","vi":"Không có chi phí vận chuyển cho các đơn hàng trên năm mươi euro.","fa":"برای سفارش های بالای پنجاه یورو هزینه حمل و نقل وجود ندارد."},{"de":"Achte beim Online-Kauf immer auf die Versandkosten.","en":"Always pay attention to the shipping costs when buying online.","ru":"При покупке онлайн всегда обращай внимание на стоимость доставки.","vi":"Khi mua hàng trực tuyến, hãy luôn chú ý đến chi phí vận chuyển.","fa":"هنگام خرید آنلاین، همیشه به هزینه حمل و نقل توجه کنید."}]},{"word":"versäumen","en":"to miss, to fail to do (something)","ru":"упустить, пропустить","vi":"bỏ lỡ","fa":"از دست دادن","examples":[{"de":"Er hat es versäumt, sich rechtzeitig anzumelden.","en":"He failed to register in time.","ru":"Он не успел вовремя зарегистрироваться.","vi":"Anh ấy đã không đăng ký đúng hạn.","fa":"او نتوانست به موقع ثبت نام کند."},{"de":"Wegen Krankheit hat sie viele Schulstunden versäumt.","en":"Due to illness, she missed many school lessons.","ru":"Из-за болезни она пропустила много уроков.","vi":"Cô đã bỏ lỡ nhiều bài học ở trường vì bệnh tật.","fa":"او بسیاری از دروس مدرسه را به دلیل بیماری از دست داد."}]},{"word":"verschieben","en":"to postpone; to move, shift","ru":"переносить, откладывать; сдвигать","vi":"di chuyển","fa":"حرکت کنید","examples":[{"de":"Wir müssen das Treffen auf nächste Woche verschieben.","en":"We have to postpone the meeting until next week.","ru":"Нам нужно перенести встречу на следующую неделю.","vi":"Chúng ta phải hoãn cuộc họp sang tuần sau.","fa":"باید جلسه را به هفته آینده موکول کنیم."},{"de":"Kannst du den Schrank ein Stück nach links verschieben?","en":"Can you shift the wardrobe a bit to the left?","ru":"Можешь сдвинуть шкаф немного влево?","vi":"Bạn có thể di chuyển cái tủ sang bên trái một chút được không?","fa":"آیا می توانید کمد را کمی به سمت چپ حرکت دهید؟"}]},{"word":"verschieden","en":"different, various","ru":"различный, разный","vi":"khác nhau","fa":"متفاوت است","examples":[{"de":"Die Geschwister haben ganz verschiedene Charaktere.","en":"The siblings have very different characters.","ru":"У братьев и сестёр совершенно разные характеры.","vi":"Hai anh em có tính cách rất khác nhau.","fa":"خواهر و برادر شخصیت های بسیار متفاوتی دارند."},{"de":"Im Laden gibt es verschiedene Sorten Käse.","en":"The shop has various kinds of cheese.","ru":"В магазине есть разные сорта сыра.","vi":"Có nhiều loại phô mai khác nhau trong cửa hàng.","fa":"انواع پنیر در فروشگاه موجود است."}]},{"word":"die Verschlüsselung","en":"encryption","ru":"шифрование","vi":"sự mã hóa","fa":"رمزگذاری","examples":[{"de":"Die App schützt deine Nachrichten durch Verschlüsselung.","en":"The app protects your messages through encryption.","ru":"Приложение защищает твои сообщения шифрованием.","vi":"Ứng dụng này bảo vệ tin nhắn của bạn bằng mã hóa.","fa":"این برنامه از پیام های شما با رمزگذاری محافظت می کند."},{"de":"Ohne Verschlüsselung könnte jeder die Daten mitlesen.","en":"Without encryption anyone could read the data.","ru":"Без шифрования любой мог бы читать эти данные.","vi":"Nếu không mã hóa, bất kỳ ai cũng có thể đọc được dữ liệu.","fa":"بدون رمزگذاری، هر کسی می تواند داده ها را بخواند."},{"de":"Diese Verschlüsselung gilt als sehr sicher.","en":"This encryption is considered very secure.","ru":"Это шифрование считается очень надёжным.","vi":"Mã hóa này được coi là rất an toàn.","fa":"این رمزگذاری بسیار امن در نظر گرفته می شود."}]},{"word":"die Verschmutzung","en":"pollution","ru":"загрязнение","vi":"sự ô nhiễm","fa":"آلودگی","examples":[{"de":"Die Verschmutzung der Meere ist ein großes Problem.","en":"The pollution of the oceans is a big problem.","ru":"Загрязнение океанов — большая проблема.","vi":"Ô nhiễm đại dương là một vấn đề lớn.","fa":"آلودگی اقیانوس ها یک مشکل بزرگ است."},{"de":"Der Verkehr trägt stark zur Verschmutzung der Luft bei.","en":"Traffic contributes greatly to air pollution.","ru":"Транспорт сильно способствует загрязнению воздуха.","vi":"Giao thông góp phần nặng nề vào ô nhiễm không khí.","fa":"ترافیک به شدت در آلودگی هوا نقش دارد."}]},{"word":"verschreiben","en":"to prescribe (medicine)","ru":"прописывать (лекарство)","vi":"quy định","fa":"تجویز کند","examples":[{"de":"Der Arzt hat mir ein Antibiotikum verschrieben.","en":"The doctor prescribed me an antibiotic.","ru":"Врач прописал мне антибиотик.","vi":"Bác sĩ kê cho tôi một loại thuốc kháng sinh.","fa":"دکتر برام آنتی بیوتیک تجویز کرد."},{"de":"Welche Tabletten hat Ihnen der Arzt verschrieben?","en":"Which pills did the doctor prescribe for you?","ru":"Какие таблетки прописал вам врач?","vi":"Bác sĩ kê đơn thuốc gì cho bạn?","fa":"دکتر کدام قرص را برای شما تجویز کرده است؟"}]},{"word":"die Verschwendung","en":"waste, wastefulness","ru":"расточительство, разбазаривание","vi":"sự lãng phí","fa":"زباله","examples":[{"de":"Die Verschwendung von Lebensmitteln ist ein großes Problem.","en":"The wasting of food is a big problem.","ru":"Разбазаривание продуктов — большая проблема.","vi":"Lãng phí thực phẩm là một vấn đề lớn.","fa":"ضایعات مواد غذایی یک مشکل بزرگ است."},{"de":"Das ist reine Verschwendung von Energie.","en":"That is a sheer waste of energy.","ru":"Это чистое расточительство энергии.","vi":"Đây là một sự lãng phí hoàn toàn năng lượng.","fa":"این اتلاف کامل انرژی است."},{"de":"Gegen die Verschwendung von Wasser kann jeder etwas tun.","en":"Everyone can do something against the waste of water.","ru":"Против расточительства воды каждый может что-то сделать.","vi":"Mọi người đều có thể làm điều gì đó để ngăn chặn việc lãng phí nước.","fa":"هر کس می تواند کاری انجام دهد تا از هدر رفتن آب جلوگیری کند."}]},{"word":"verschwinden","en":"to disappear","ru":"исчезать","vi":"biến mất","fa":"ناپدید می شوند","examples":[{"de":"Die Sonne verschwand hinter den Wolken.","en":"The sun disappeared behind the clouds.","ru":"Солнце исчезло за облаками.","vi":"Mặt trời biến mất sau những đám mây.","fa":"خورشید پشت ابرها ناپدید شد."},{"de":"Mein Portemonnaie ist plötzlich verschwunden.","en":"My wallet suddenly disappeared.","ru":"Мой кошелёк вдруг пропал.","vi":"Ví của tôi đột nhiên biến mất.","fa":"کیف پولم ناگهان ناپدید شد."}]},{"word":"versenden","en":"to send off or dispatch (a message, request)","ru":"отправлять, рассылать (сообщение, запрос)","vi":"gửi","fa":"ارسال کنید","examples":[{"de":"Man kann Freundschaftsanfragen versenden und erhalten.","en":"You can send and receive friend requests.","ru":"Можно отправлять и получать запросы в друзья.","vi":"Bạn có thể gửi và nhận yêu cầu kết bạn.","fa":"می توانید درخواست های دوستی را ارسال و دریافت کنید."},{"de":"Die Firma versendet die Rechnung normalerweise per E-Mail.","en":"The company normally sends the invoice by email.","ru":"Компания обычно отправляет счёт по электронной почте.","vi":"Công ty thường gửi hóa đơn qua email.","fa":"شرکت معمولا فاکتور را از طریق ایمیل ارسال می کند."},{"de":"Bitte versenden Sie das Formular bis Freitag.","en":"Please send off the form by Friday.","ru":"Пожалуйста, отправьте формуляр до пятницы.","vi":"Vui lòng gửi mẫu đơn trước thứ Sáu.","fa":"لطفا فرم را تا جمعه ارسال کنید."}]},{"word":"versichern","en":"to insure; to assure","ru":"страховать; уверять","vi":"bảo đảm","fa":"بیمه کنند","examples":[{"de":"Er hat sein Auto gegen Diebstahl versichert.","en":"He insured his car against theft.","ru":"Он застраховал свою машину от кражи.","vi":"Anh ta đã mua bảo hiểm cho chiếc xe của mình chống trộm.","fa":"او خودروی خود را در برابر سرقت بیمه کرده است."},{"de":"Ich versichere Ihnen, dass alles in Ordnung ist.","en":"I assure you that everything is fine.","ru":"Я уверяю вас, что всё в порядке.","vi":"Tôi đảm bảo với bạn rằng mọi thứ đều ổn.","fa":"من به شما اطمینان می دهم که همه چیز خوب است."}]},{"word":"die Versichertenkarte","en":"health insurance card","ru":"карта медицинского страхования","vi":"thẻ bảo hiểm","fa":"کارت بیمه","examples":[{"de":"Bitte zeigen Sie mir Ihre Versichertenkarte beim Arztbesuch.","en":"Please show me your health insurance card at the doctor's visit.","ru":"Пожалуйста, покажите вашу карту медицинского страхования на приёме у врача.","vi":"Vui lòng cho tôi xem thẻ bảo hiểm của bạn khi bạn đến gặp bác sĩ.","fa":"لطفاً هنگام مراجعه به پزشک کارت بیمه خود را به من نشان دهید."},{"de":"Ich habe meine Versichertenkarte zu Hause vergessen.","en":"I forgot my health insurance card at home.","ru":"Я забыл дома свою карту медицинского страхования.","vi":"Tôi quên thẻ bảo hiểm ở nhà.","fa":"کارت بیمه ام را در خانه فراموش کردم."}]},{"word":"die Versicherung","en":"insurance","ru":"страховка","vi":"bảo hiểm","fa":"بیمه","examples":[{"de":"Ohne Versicherung darf man nicht Auto fahren.","en":"You are not allowed to drive a car without insurance.","ru":"Без страховки нельзя водить машину.","vi":"Bạn không được phép lái xe mà không có bảo hiểm.","fa":"شما مجاز به رانندگی بدون بیمه نیستید."},{"de":"Die Versicherung zahlt den Schaden nicht.","en":"The insurance won't pay for the damage.","ru":"Страховка не покрывает ущерб.","vi":"Bảo hiểm không bồi thường thiệt hại.","fa":"بیمه خسارت را پرداخت نمی کند."}]},{"word":"der Versicherungsbeitrag","en":"insurance premium, insurance contribution","ru":"страховой взнос","vi":"đóng góp bảo hiểm","fa":"سهم بیمه","examples":[{"de":"Der Versicherungsbeitrag wird monatlich von meinem Konto abgebucht.","en":"The insurance premium is debited from my account monthly.","ru":"Страховой взнос ежемесячно списывается с моего счёта.","vi":"Phí bảo hiểm được trừ vào tài khoản của tôi hàng tháng.","fa":"حق بیمه ماهیانه از حساب من کسر می شود."},{"de":"Der Versicherungsbeitrag ist in diesem Jahr leider gestiegen.","en":"The insurance contribution has unfortunately risen this year.","ru":"Страховой взнос, к сожалению, вырос в этом году.","vi":"Thật không may, phí bảo hiểm đã tăng lên trong năm nay.","fa":"متاسفانه امسال حق بیمه افزایش یافته است."},{"de":"Wie hoch ist der Versicherungsbeitrag für ein Auto?","en":"How high is the insurance premium for a car?","ru":"Насколько высок страховой взнос за автомобиль?","vi":"Phí bảo hiểm cho ô tô là bao nhiêu?","fa":"حق بیمه خودرو چقدر است؟"}]},{"word":"der Versicherungsschutz","en":"insurance cover","ru":"страховое покрытие","vi":"phạm vi bảo hiểm","fa":"پوشش بیمه ای","examples":[{"de":"Ohne ausreichenden Versicherungsschutz solltest du nicht ins Ausland reisen.","en":"You shouldn't travel abroad without sufficient insurance cover.","ru":"Не стоит ехать за границу без достаточного страхового покрытия.","vi":"Bạn không nên đi du lịch nước ngoài mà không có bảo hiểm đầy đủ.","fa":"شما نباید بدون پوشش بیمه کافی به خارج از کشور سفر کنید."},{"de":"Der Versicherungsschutz gilt auch für Schäden im Haushalt.","en":"The insurance cover also applies to damage in the home.","ru":"Страховое покрытие распространяется и на ущерб в квартире.","vi":"Bảo hiểm cũng áp dụng cho thiệt hại của hộ gia đình.","fa":"پوشش بیمه ای در مورد خسارت وارده به خانواده نیز اعمال می شود."},{"de":"Prüfen Sie bitte, ob Ihr Versicherungsschutz noch aktuell ist.","en":"Please check whether your insurance cover is still up to date.","ru":"Проверьте, актуально ли ещё ваше страховое покрытие.","vi":"Vui lòng kiểm tra xem bảo hiểm của bạn có còn hiệu lực hay không.","fa":"لطفا بررسی کنید که آیا پوشش بیمه شما هنوز جاری است یا خیر."}]},{"word":"die Versiegelung","en":"sealing (of soil/land)","ru":"запечатывание почвы (застройка непроницаемым покрытием)","vi":"niêm phong","fa":"آب بندی","examples":[{"de":"Die Versiegelung des Bodens verschlimmert Überschwemmungen.","en":"The sealing of the soil makes floods worse.","ru":"Запечатывание почвы усугубляет наводнения.","vi":"Bịt kín mặt đất khiến lũ lụt trở nên tồi tệ hơn.","fa":"آب بندی زمین باعث بدتر شدن سیل می شود."},{"de":"Durch die Versiegelung kann der Regen nicht versickern.","en":"Because of the sealing, rain cannot seep away.","ru":"Из-за запечатывания дождь не может впитываться.","vi":"Bịt kín có nghĩa là mưa không thể thấm đi.","fa":"آب بندی به این معنی است که باران نمی تواند از بین برود."},{"de":"Die Stadt will die Versiegelung von Flächen reduzieren.","en":"The city wants to reduce the sealing of land.","ru":"Город хочет сократить запечатывание площадей.","vi":"Thành phố muốn giảm bớt việc phong tỏa các khu vực.","fa":"شهر می خواهد آب بندی مناطق را کاهش دهد."}]},{"word":"die Version","en":"version","ru":"версия","vi":"phiên bản","fa":"the version","examples":[{"de":"Welche Version der App benutzt du gerade?","en":"Which version of the app are you currently using?","ru":"Какой версией приложения ты сейчас пользуешься?","vi":"Bạn hiện đang sử dụng phiên bản nào của ứng dụng?","fa":"در حال حاضر از کدام نسخه برنامه استفاده می کنید؟"},{"de":"Die neueste Version läuft viel stabiler als die alte.","en":"The latest version runs much more stably than the old one.","ru":"Новейшая версия работает намного стабильнее старой.","vi":"Phiên bản mới nhất ổn định hơn nhiều so với phiên bản cũ.","fa":"آخرین نسخه بسیار پایدارتر از نسخه قدیمی است."},{"de":"Vom Wörterbuch gibt es auch eine kostenlose Version.","en":"There's also a free version of the dictionary.","ru":"У словаря есть и бесплатная версия.","vi":"Ngoài ra còn có một phiên bản miễn phí của từ điển.","fa":"همچنین یک نسخه رایگان از فرهنگ لغت وجود دارد."}]},{"word":"verspannt","en":"tense, stiff","ru":"зажатый, скованный, напряжённый","vi":"căng thẳng","fa":"متشنج","examples":[{"de":"Mein Nacken ist nach der Arbeit oft verspannt.","en":"My neck is often tense after work.","ru":"Моя шея после работы часто зажата.","vi":"Cổ tôi thường bị căng sau giờ làm việc.","fa":"گردن من اغلب بعد از کار متشنج است."},{"de":"Diese Übung löst die verspannten Schultern.","en":"This exercise releases the tense shoulders.","ru":"Это упражнение снимает напряжение с зажатых плеч.","vi":"Bài tập này giải phóng đôi vai căng thẳng.","fa":"این تمرین شانه های تنش را آزاد می کند."},{"de":"Wenn du verspannt bist, hilft langsames Atmen.","en":"When you are tense, slow breathing helps.","ru":"Когда ты напряжён, помогает медленное дыхание.","vi":"Nếu bạn căng thẳng, thở chậm sẽ có ích.","fa":"اگر تنش دارید، نفس کشیدن آهسته کمک می کند."}]},{"word":"die Verspätung","en":"delay","ru":"опоздание, задержка","vi":"sự chậm trễ","fa":"تاخیر","examples":[{"de":"Der Zug hat heute zwanzig Minuten Verspätung.","en":"The train is twenty minutes late today.","ru":"Поезд сегодня опаздывает на двадцать минут.","vi":"Hôm nay tàu trễ hai mươi phút.","fa":"قطار امروز بیست دقیقه تاخیر دارد."},{"de":"Wegen der Verspätung habe ich meinen Anschlussflug verpasst.","en":"Because of the delay, I missed my connecting flight.","ru":"Из-за задержки я пропустил стыковочный рейс.","vi":"Vì sự chậm trễ nên tôi đã lỡ chuyến bay nối chuyến.","fa":"به دلیل تاخیر، پرواز اتصالم را از دست دادم."}]},{"word":"die Verspätung melden","en":"to report a delay","ru":"сообщить об опоздании (о задержке)","vi":"báo cáo sự chậm trễ","fa":"تاخیر را گزارش کنید","examples":[{"de":"Der Schaffner musste die Verspätung melden.","en":"The conductor had to report the delay.","ru":"Кондуктор должен был сообщить о задержке.","vi":"Người soát vé đã phải báo cáo sự chậm trễ.","fa":"هادی باید تاخیر را گزارش می کرد."},{"de":"Bitte melden Sie die Verspätung dem Personal.","en":"Please report the delay to the staff.","ru":"Пожалуйста, сообщите о задержке персоналу.","vi":"Vui lòng báo cáo sự chậm trễ cho nhân viên.","fa":"لطفا تاخیر را به کارکنان گزارش دهید."},{"de":"Sie hat die Verspätung pünktlich gemeldet.","en":"She reported the delay on time.","ru":"Она вовремя сообщила о задержке.","vi":"Cô báo cáo sự chậm trễ đúng giờ.","fa":"او تأخیر را به موقع گزارش کرد."}]},{"word":"die Verspätungsmeldung","en":"delay announcement","ru":"сообщение о задержке (рейса, поезда)","vi":"báo cáo chậm trễ","fa":"گزارش تاخیر","examples":[{"de":"Die Verspätungsmeldung kam erst zehn Minuten vor der Abfahrt.","en":"The delay announcement came only ten minutes before departure.","ru":"Сообщение о задержке пришло всего за десять минут до отправления.","vi":"Báo cáo về sự chậm trễ chỉ đến mười phút trước khi khởi hành.","fa":"گزارش تاخیر فقط ده دقیقه قبل از حرکت آمده است."},{"de":"Nach der Verspätungsmeldung haben viele Reisende den Bahnhof verlassen.","en":"After the delay announcement, many travellers left the station.","ru":"После сообщения о задержке многие пассажиры покинули вокзал.","vi":"Sau khi thông báo chậm trễ, nhiều du khách đã rời ga.","fa":"پس از گزارش تاخیر، بسیاری از مسافران ایستگاه را ترک کردند."},{"de":"Hast du die Verspätungsmeldung auf der Anzeigetafel gesehen?","en":"Did you see the delay announcement on the display board?","ru":"Ты видел сообщение о задержке на табло?","vi":"Bạn có thấy thông báo trì hoãn trên bảng điểm không?","fa":"آیا پیام تاخیر را روی تابلوی امتیاز دیدید؟"}]},{"word":"versprechen","en":"to promise","ru":"обещать","vi":"lời hứa","fa":"قول دادن","examples":[{"de":"Er hat mir versprochen, pünktlich zu sein.","en":"He promised me to be on time.","ru":"Он пообещал мне быть вовремя.","vi":"Anh ấy đã hứa với tôi là sẽ đến đúng giờ.","fa":"او به من قول داد که به موقع خواهد آمد."},{"de":"Versprich mir, dass du auf dich aufpasst.","en":"Promise me that you'll take care of yourself.","ru":"Обещай мне, что будешь беречь себя.","vi":"Hãy hứa với tôi là bạn sẽ tự chăm sóc bản thân.","fa":"به من قول بده که مواظب خودت باشی"}]},{"word":"verständlich","en":"understandable, comprehensible","ru":"понятный","vi":"có thể hiểu được","fa":"قابل درک","examples":[{"de":"Der Lehrer erklärt die Grammatik sehr verständlich.","en":"The teacher explains the grammar very understandably.","ru":"Учитель объясняет грамматику очень понятно.","vi":"Thầy giảng ngữ pháp rất rõ ràng.","fa":"معلم گرامر را خیلی واضح توضیح می دهد."},{"de":"Es ist verständlich, dass du enttäuscht bist.","en":"It's understandable that you're disappointed.","ru":"Понятно, что ты разочарован.","vi":"Việc bạn thất vọng là điều dễ hiểu.","fa":"قابل درک است که شما ناامید شده اید."}]},{"word":"das Verständnis","en":"understanding, sympathy","ru":"понимание, сочувствие","vi":"sự hiểu biết","fa":"درک","examples":[{"de":"Ich habe vollstes Verständnis für deine Entscheidung.","en":"I have complete understanding for your decision.","ru":"Я полностью понимаю твоё решение.","vi":"Tôi hoàn toàn hiểu quyết định của bạn.","fa":"من کاملا تصمیم شما را درک می کنم."},{"de":"Vielen Dank für Ihr Verständnis in dieser Angelegenheit.","en":"Thank you very much for your understanding in this matter.","ru":"Большое спасибо за понимание в этом вопросе.","vi":"Cảm ơn bạn đã hiểu biết về vấn đề này.","fa":"از درک شما در این مورد متشکرم."},{"de":"Sein Verständnis von Gerechtigkeit ist anders als meins.","en":"His understanding of justice is different from mine.","ru":"Его представление о справедливости отличается от моего.","vi":"Sự hiểu biết của anh ấy về công lý khác với tôi.","fa":"درک او از عدالت با من متفاوت است."}]},{"word":"verstecken","en":"to hide","ru":"прятать(ся)","vi":"trốn","fa":"پنهان کردن","examples":[{"de":"Die Kinder verstecken sich hinter dem Sofa.","en":"The children are hiding behind the sofa.","ru":"Дети прячутся за диваном.","vi":"Bọn trẻ trốn sau ghế sofa.","fa":"بچه ها پشت مبل پنهان می شوند."},{"de":"Wo hast du die Geschenke versteckt?","en":"Where did you hide the presents?","ru":"Куда ты спрятал подарки?","vi":"Bạn đã giấu những món quà ở đâu?","fa":"هدایا را کجا پنهان کردی؟"},{"de":"Er versteckte den Brief in der Schublade.","en":"He hid the letter in the drawer.","ru":"Он спрятал письмо в ящик.","vi":"Anh giấu lá thư vào ngăn kéo.","fa":"نامه را در کشو پنهان کرد."}]},{"word":"der Versuch","en":"attempt; experiment","ru":"попытка; опыт (эксперимент)","vi":"nỗ lực","fa":"تلاش","examples":[{"de":"Beim zweiten Versuch hat es geklappt.","en":"It worked on the second attempt.","ru":"Со второй попытки получилось.","vi":"Nó hoạt động ở lần thử thứ hai.","fa":"در تلاش دوم جواب داد."},{"de":"Es war zumindest einen Versuch wert.","en":"It was at least worth a try.","ru":"По крайней мере, попытка того стоила.","vi":"Ít nhất thì nó cũng đáng để thử.","fa":"حداقل ارزش امتحان کردن را داشت."},{"de":"Der Versuch im Labor dauerte mehrere Stunden.","en":"The experiment in the lab took several hours.","ru":"Опыт в лаборатории длился несколько часов.","vi":"Thí nghiệm trong phòng thí nghiệm kéo dài vài giờ.","fa":"آزمایش در آزمایشگاه چندین ساعت به طول انجامید."}]},{"word":"versuchen","en":"to try","ru":"пытаться, пробовать","vi":"thử","fa":"سعی کنید","examples":[{"de":"Ich versuche, jeden Tag Sport zu machen.","en":"I try to exercise every day.","ru":"Я стараюсь заниматься спортом каждый день.","vi":"Tôi cố gắng tập thể dục mỗi ngày.","fa":"سعی می کنم هر روز ورزش کنم."},{"de":"Versuch doch mal dieses neue Rezept!","en":"Try this new recipe!","ru":"Попробуй этот новый рецепт!","vi":"Hãy thử công thức mới này!","fa":"این دستور جدید را امتحان کنید!"}]},{"word":"der Versuchsaufbau","en":"experimental setup","ru":"схема (постановка) эксперимента, экспериментальная установка","vi":"thiết lập thử nghiệm","fa":"تنظیم آزمایشی","examples":[{"de":"Der Versuchsaufbau stand bereits auf dem Tisch.","en":"The experimental setup was already on the table.","ru":"Экспериментальная установка уже стояла на столе.","vi":"Thiết lập thử nghiệm đã có sẵn trên bàn.","fa":"تنظیم آزمایشی از قبل روی میز بود."},{"de":"Wir überprüften den Versuchsaufbau vor dem Start.","en":"We checked the experimental setup before starting.","ru":"Мы проверили экспериментальную установку перед началом.","vi":"Chúng tôi đã kiểm tra thiết lập thử nghiệm trước khi bắt đầu.","fa":"قبل از شروع، تنظیمات آزمایشی را بررسی کردیم."},{"de":"Ein einfacher Versuchsaufbau genügt für dieses Experiment.","en":"A simple experimental setup is enough for this experiment.","ru":"Для этого опыта достаточно простой установки.","vi":"Một thiết lập thử nghiệm đơn giản là đủ cho thử nghiệm này.","fa":"یک تنظیم آزمایشی ساده برای این آزمایش کافی است."}]},{"word":"verteilen","en":"to distribute, to hand out","ru":"распределять, раздавать","vi":"phân phối","fa":"توزیع کنید","examples":[{"de":"Der Lehrer verteilte die Arbeitsblätter an die Schüler.","en":"The teacher handed out the worksheets to the students.","ru":"Учитель раздал ученикам рабочие листы.","vi":"Giáo viên phát bài tập cho học sinh.","fa":"معلم برگه ها را بین دانش آموزان توزیع کرد."},{"de":"Die Aufgaben wurden gleichmäßig unter den Kollegen verteilt.","en":"The tasks were distributed evenly among the colleagues.","ru":"Задачи были равномерно распределены между коллегами.","vi":"Nhiệm vụ được phân bổ đều cho các đồng nghiệp.","fa":"وظایف به طور مساوی بین همکاران توزیع شد."}]},{"word":"die Verteilung","en":"distribution","ru":"распределение","vi":"sự phân phối","fa":"توزیع","examples":[{"de":"Die Verteilung der Werte ist sehr ungleich.","en":"The distribution of the values is very uneven.","ru":"Распределение значений очень неравномерное.","vi":"Sự phân bổ các giá trị rất không đồng đều.","fa":"توزیع ارزش ها بسیار ناهموار است."},{"de":"Das Diagramm zeigt die Verteilung des Einkommens.","en":"The chart shows the distribution of income.","ru":"Диаграмма показывает распределение доходов.","vi":"Biểu đồ thể hiện sự phân phối thu nhập.","fa":"نمودار توزیع درآمد را نشان می دهد."},{"de":"Eine normale Verteilung ist symmetrisch.","en":"A normal distribution is symmetrical.","ru":"Нормальное распределение симметрично.","vi":"Một phân phối bình thường là đối xứng.","fa":"توزیع نرمال متقارن است."}]},{"word":"der Vertrag","en":"contract","ru":"договор","vi":"hợp đồng","fa":"قرارداد","examples":[{"de":"Bitte lesen Sie den Vertrag genau, bevor Sie unterschreiben.","en":"Please read the contract carefully before signing.","ru":"Пожалуйста, внимательно прочитайте договор, прежде чем подписать.","vi":"Vui lòng đọc kỹ hợp đồng trước khi ký.","fa":"لطفا قبل از امضا قرارداد را با دقت مطالعه کنید."},{"de":"Ihr Vertrag läuft am Ende des Jahres aus.","en":"Your contract expires at the end of the year.","ru":"Ваш договор истекает в конце года.","vi":"Hợp đồng của bạn sẽ hết hạn vào cuối năm.","fa":"قرارداد شما در پایان سال به پایان می رسد."}]},{"word":"vertragen","en":"to tolerate, to stand; (sich) to get along","ru":"переносить, терпеть; (sich) ладить, мириться","vi":"chịu đựng được","fa":"تحمل کرد","examples":[{"de":"Ich vertrage keinen Kaffee am Abend.","en":"I can't tolerate coffee in the evening.","ru":"Я не переношу кофе вечером.","vi":"Tôi không thể chịu được cà phê vào buổi tối.","fa":"من نمی توانم قهوه را در عصر تحمل کنم."},{"de":"Die beiden Brüder vertragen sich endlich wieder.","en":"The two brothers are finally getting along again.","ru":"Два брата наконец снова помирились.","vi":"Hai anh em cuối cùng cũng hòa hợp trở lại.","fa":"دو برادر بالاخره دوباره با هم کنار می آیند."},{"de":"Er verträgt die Hitze nicht gut.","en":"He doesn't tolerate the heat well.","ru":"Он плохо переносит жару.","vi":"Anh ấy không chịu được nhiệt tốt.","fa":"گرما را به خوبی تحمل نمی کند."}]},{"word":"vertrauen","en":"to trust","ru":"доверять","vi":"tin tưởng","fa":"اعتماد","examples":[{"de":"Ich vertraue meinem besten Freund vollkommen.","en":"I trust my best friend completely.","ru":"Я полностью доверяю своему лучшему другу.","vi":"Tôi hoàn toàn tin tưởng người bạn thân nhất của mình.","fa":"من به بهترین دوستم کاملاً اعتماد دارم."},{"de":"Man sollte nicht jeder Werbung vertrauen.","en":"One shouldn't trust every advertisement.","ru":"Не стоит доверять каждой рекламе.","vi":"Bạn không nên tin tưởng mọi quảng cáo.","fa":"نباید به هر تبلیغی اعتماد کرد."}]},{"word":"das Vertrauen","en":"trust; confidence","ru":"доверие","vi":"sự tin tưởng","fa":"اعتماد","examples":[{"de":"Ohne Vertrauen funktioniert keine Beziehung.","en":"No relationship works without trust.","ru":"Без доверия не работают никакие отношения.","vi":"Không có mối quan hệ nào hoạt động mà không có sự tin tưởng.","fa":"هیچ رابطه ای بدون اعتماد کار نمی کند."},{"de":"Er hat mein Vertrauen leider missbraucht.","en":"Unfortunately he abused my trust.","ru":"К сожалению, он злоупотребил моим доверием.","vi":"Thật không may, anh ấy đã phản bội lòng tin của tôi.","fa":"متاسفانه او به اعتماد من خیانت کرد."}]},{"word":"vertreten","en":"to represent; to stand in for (someone)","ru":"представлять; замещать (кого-то)","vi":"đại diện","fa":"نمایندگی کرد","examples":[{"de":"Der Anwalt vertritt seinen Mandanten vor Gericht.","en":"The lawyer represents his client in court.","ru":"Адвокат представляет своего клиента в суде.","vi":"Luật sư đại diện cho khách hàng của mình tại tòa án.","fa":"وکیل مدافع موکل خود در دادگاه است."},{"de":"Frau Müller vertritt heute den kranken Kollegen.","en":"Ms. Müller is standing in for the sick colleague today.","ru":"Госпожа Мюллер сегодня замещает заболевшего коллегу.","vi":"Hôm nay cô Müller đại diện cho đồng nghiệp bị ốm.","fa":"خانم مولر امروز نماینده همکار بیمار است."}]},{"word":"der Vertreter","en":"representative, agent","ru":"представитель; торговый агент; заместитель","vi":"người đại diện","fa":"نماینده","examples":[{"de":"Der Vertreter der Firma stellte das neue Produkt vor.","en":"The company's representative presented the new product.","ru":"Представитель компании презентовал новый продукт.","vi":"Đại diện công ty giới thiệu sản phẩm mới.","fa":"نماینده این شرکت محصول جدید را معرفی کرد."},{"de":"Als gewählter Vertreter spreche ich für die ganze Gruppe.","en":"As an elected representative I speak for the whole group.","ru":"Как избранный представитель я говорю от лица всей группы.","vi":"Với tư cách là đại diện được bầu, tôi phát biểu thay mặt cho cả nhóm.","fa":"من به عنوان یک نماینده منتخب از طرف کل گروه صحبت می کنم."},{"de":"Ein Vertreter klingelte an der Tür und wollte Staubsauger verkaufen.","en":"A salesman rang the doorbell and wanted to sell vacuum cleaners.","ru":"Торговый агент позвонил в дверь и хотел продать пылесосы.","vi":"Một người bán hàng bấm chuông và muốn bán máy hút bụi.","fa":"فروشنده ای زنگ در را زد و می خواست جاروبرقی بفروشد."}]},{"word":"die Vertreterin","en":"representative (female), agent (female)","ru":"представительница; торговый агент (женщина)","vi":"người đại diện","fa":"نماینده","examples":[{"de":"Die Vertreterin der Gewerkschaft hielt eine kurze Rede.","en":"The union's representative gave a short speech.","ru":"Представительница профсоюза произнесла короткую речь.","vi":"Đại diện công đoàn phát biểu ngắn gọn.","fa":"نماینده اتحادیه سخنرانی کوتاهی کرد."},{"de":"Sie ist eine erfolgreiche Vertreterin für Kosmetik.","en":"She is a successful sales representative for cosmetics.","ru":"Она успешный торговый агент по косметике.","vi":"Cô là một đại diện mỹ phẩm thành công.","fa":"او یک نماینده موفق لوازم آرایشی است."},{"de":"Als Vertreterin der Eltern nahm sie an der Sitzung teil.","en":"As a representative of the parents she took part in the meeting.","ru":"Как представительница родителей она приняла участие в собрании.","vi":"Cô tham dự cuộc họp với tư cách là đại diện của phụ huynh.","fa":"وی به عنوان نماینده والدین در این جلسه شرکت کرد."}]},{"word":"die Vertretung","en":"replacement, cover, representation","ru":"замещение, замена, представительство","vi":"sự đại diện","fa":"نمایندگی","examples":[{"de":"Während ihrer Krankheit übernahm ich die Vertretung.","en":"During her illness I took over as cover.","ru":"Во время её болезни я взял на себя замещение.","vi":"Trong thời gian cô ấy bị bệnh, tôi đã đảm nhận vai trò thay thế.","fa":"در طول بیماری او من به عنوان جایگزین به عهده گرفتم."},{"de":"Die diplomatische Vertretung des Landes liegt im Zentrum.","en":"The country's diplomatic mission is located in the centre.","ru":"Дипломатическое представительство страны находится в центре.","vi":"Nhiệm vụ ngoại giao của đất nước là ở trung tâm.","fa":"هیئت دیپلماتیک این کشور در مرکز قرار دارد."},{"de":"Wir suchen dringend eine Vertretung für den erkrankten Lehrer.","en":"We urgently need a substitute for the sick teacher.","ru":"Нам срочно нужна замена заболевшему учителю.","vi":"Chúng tôi đang khẩn trương tìm người thay thế giáo viên bị bệnh.","fa":"ما به دنبال جایگزینی برای معلم بیمار هستیم."}]},{"word":"verursachen","en":"to cause","ru":"вызывать, быть причиной","vi":"nguyên nhân","fa":"علت","examples":[{"de":"Der Unfall wurde durch Glatteis verursacht.","en":"The accident was caused by black ice.","ru":"Авария была вызвана гололёдом.","vi":"Vụ tai nạn xảy ra do băng đen.","fa":"علت این حادثه یخ سیاه بوده است."},{"de":"Rauchen kann viele Krankheiten verursachen.","en":"Smoking can cause many illnesses.","ru":"Курение может вызывать много болезней.","vi":"Hút thuốc có thể gây ra nhiều bệnh tật.","fa":"سیگار می تواند باعث بسیاری از بیماری ها شود."}]},{"word":"verurteilen","en":"to convict, to condemn","ru":"осуждать, приговаривать","vi":"lên án","fa":"محکوم کردن","examples":[{"de":"Das Gericht hat ihn zu einer Geldstrafe verurteilt.","en":"The court sentenced him to a fine.","ru":"Суд приговорил его к штрафу.","vi":"Tòa án đã kết án anh ta phạt tiền.","fa":"دادگاه او را به جریمه نقدی محکوم کرد."},{"de":"Viele Menschen verurteilen Gewalt in jeder Form.","en":"Many people condemn violence in any form.","ru":"Многие люди осуждают насилие в любой форме.","vi":"Nhiều người lên án bạo lực dưới mọi hình thức.","fa":"بسیاری از مردم خشونت را در همه اشکال محکوم می کنند."}]},{"word":"die Verwaltung","en":"administration","ru":"администрация, управление","vi":"chính quyền","fa":"اداره","examples":[{"de":"Die Verwaltung der Stadt ist für die Straßen zuständig.","en":"The city's administration is responsible for the streets.","ru":"Администрация города отвечает за дороги.","vi":"Chính quyền thành phố chịu trách nhiệm về đường bộ.","fa":"مدیریت شهری مسئول راه هاست."},{"de":"Sie arbeitet in der Verwaltung eines Krankenhauses.","en":"She works in the administration of a hospital.","ru":"Она работает в администрации больницы.","vi":"Cô ấy làm việc ở bộ phận hành chính tại một bệnh viện.","fa":"او در بخش مدیریت در بیمارستان کار می کند."}]},{"word":"verwandt","en":"related (family)","ru":"родственный, состоящий в родстве","vi":"liên quan","fa":"مرتبط","examples":[{"de":"Wir sind entfernt miteinander verwandt.","en":"We are distantly related to each other.","ru":"Мы дальние родственники.","vi":"Chúng tôi có họ hàng xa.","fa":"ما از دور با هم مرتبطیم."},{"de":"Ist er mit dir verwandt oder nur ein Freund?","en":"Is he related to you or just a friend?","ru":"Он твой родственник или просто друг?","vi":"Anh ấy có họ hàng với bạn hay chỉ là một người bạn?","fa":"آیا او با شما نسبت دارد یا فقط یک دوست؟"}]},{"word":"der Verwandtenbesuch","en":"visit to relatives","ru":"визит к родственникам, поездка в гости к родне","vi":"thăm thân nhân","fa":"بازدید از اقوام","examples":[{"de":"Am Wochenende steht ein Verwandtenbesuch an.","en":"A visit to relatives is coming up at the weekend.","ru":"На выходных предстоит визит к родственникам.","vi":"Cuối tuần có người thân đến thăm.","fa":"یکی از اقوام آخر هفته به دیدنش می آید."},{"de":"Der Verwandtenbesuch hat den ganzen Sonntag gedauert.","en":"The visit to relatives lasted the whole Sunday.","ru":"Визит к родственникам занял всё воскресенье.","vi":"Chuyến thăm họ hàng kéo dài cả ngày Chủ nhật.","fa":"دیدار با بستگان تمام یکشنبه طول کشید."},{"de":"Wir freuen uns auf den Verwandtenbesuch im Sommer.","en":"We are looking forward to the visit to relatives in the summer.","ru":"Мы с нетерпением ждём визита к родственникам летом.","vi":"Chúng tôi mong được đến thăm người thân vào mùa hè.","fa":"ما مشتاقانه منتظر دیدار اقوام در تابستان هستیم."}]},{"word":"die Verwandtschaft","en":"one's relatives, extended family","ru":"родня, родственники","vi":"những người thân","fa":"the relatives","examples":[{"de":"Auf der großen Hochzeit sieht man die gesamte Verwandtschaft.","en":"At the big wedding you see the entire extended family.","ru":"На большой свадьбе видишь всю родню.","vi":"Tại đám cưới lớn, bạn có thể nhìn thấy tất cả người thân.","fa":"در عروسی بزرگ می توانید همه اقوام را ببینید."},{"de":"Zu Weihnachten kommt die ganze Verwandtschaft zu uns.","en":"At Christmas the whole extended family comes to our place.","ru":"На Рождество к нам собирается вся родня.","vi":"Cả gia đình đến với chúng tôi vào dịp Giáng sinh.","fa":"تمام خانواده برای کریسمس به ما می آیند."},{"de":"Ein Teil meiner Verwandtschaft lebt in Kanada.","en":"Part of my extended family lives in Canada.","ru":"Часть моих родственников живёт в Канаде.","vi":"Một số người thân của tôi sống ở Canada.","fa":"برخی از اقوام من در کانادا زندگی می کنند."}]},{"word":"verwechseln","en":"to confuse, to mix up","ru":"путать","vi":"trộn lẫn","fa":"مخلوط کردن","examples":[{"de":"Entschuldigung, ich habe Sie mit jemand anderem verwechselt.","en":"Sorry, I mixed you up with someone else.","ru":"Извините, я перепутал вас с кем-то другим.","vi":"Xin lỗi, tôi đã nhầm lẫn bạn với người khác.","fa":"ببخشید من شما رو با یکی دیگه اشتباه گرفتم"},{"de":"Die Zwillinge sehen sich so ähnlich, dass man sie leicht verwechseln kann.","en":"The twins look so alike that you can easily confuse them.","ru":"Близнецы так похожи, что их легко перепутать.","vi":"Cặp song sinh trông giống nhau đến mức dễ bị nhầm lẫn.","fa":"دوقلوها آنقدر شبیه به هم هستند که به راحتی می توان آنها را گیج کرد."}]},{"word":"verwenden","en":"to use","ru":"использовать","vi":"sử dụng","fa":"استفاده کنید","examples":[{"de":"Für den Kuchen verwende ich frische Eier.","en":"I use fresh eggs for the cake.","ru":"Для торта я использую свежие яйца.","vi":"Tôi sử dụng trứng tươi cho bánh.","fa":"من از تخم مرغ تازه برای کیک استفاده می کنم."},{"de":"Man kann diese App kostenlos verwenden.","en":"You can use this app for free.","ru":"Этим приложением можно пользоваться бесплатно.","vi":"Người ta có thể sử dụng ứng dụng này miễn phí.","fa":"می توانید از این برنامه به صورت رایگان استفاده کنید."}]},{"word":"verwirrt","en":"confused, bewildered","ru":"растерянный, сбитый с толку","vi":"bối rối","fa":"گیج شده","examples":[{"de":"Nach der langen Reise war ich völlig verwirrt.","en":"After the long journey I was completely confused.","ru":"После долгой поездки я был совершенно растерян.","vi":"Sau cuộc hành trình dài tôi hoàn toàn bối rối.","fa":"بعد از سفر طولانی کاملا گیج شدم."},{"de":"Deine Frage hat mich ganz verwirrt.","en":"Your question confused me completely.","ru":"Твой вопрос совсем сбил меня с толку.","vi":"Câu hỏi của bạn thực sự làm tôi bối rối.","fa":"سوال شما واقعا مرا گیج کرد."},{"de":"Er sah mich mit einem verwirrten Blick an.","en":"He looked at me with a bewildered expression.","ru":"Он смотрел на меня растерянным взглядом.","vi":"Anh ấy nhìn tôi với ánh mắt bối rối.","fa":"با نگاهی گیج به من نگاه کرد."}]},{"word":"verzeihen","en":"to forgive","ru":"прощать","vi":"tha thứ","fa":"ببخش","examples":[{"de":"Kannst du mir meinen Fehler verzeihen?","en":"Can you forgive me for my mistake?","ru":"Ты можешь простить мне мою ошибку?","vi":"Bạn có thể tha thứ cho lỗi lầm của tôi được không?","fa":"آیا می توانی مرا به خاطر اشتباهم ببخشی؟"},{"de":"Sie hat ihm nie verziehen, dass er sie belogen hat.","en":"She never forgave him for lying to her.","ru":"Она так и не простила ему, что он её обманул.","vi":"Cô không bao giờ tha thứ cho anh vì đã nói dối cô.","fa":"هرگز او را به خاطر دروغ گفتن به او نبخشید."}]},{"word":"die Verzeihung","en":"forgiveness; excuse me","ru":"прощение; извините","vi":"sự tha thứ","fa":"عفو","examples":[{"de":"Verzeihung, können Sie mir den Weg zum Bahnhof zeigen?","en":"Excuse me, can you show me the way to the station?","ru":"Извините, вы можете показать мне дорогу к вокзалу?","vi":"Xin lỗi, bạn có thể chỉ cho tôi đường đến ga xe lửa được không?","fa":"ببخشید میشه راه ایستگاه قطار رو به من نشون بدید؟"},{"de":"Ich bitte dich um Verzeihung für mein hartes Wort.","en":"I ask you for forgiveness for my harsh word.","ru":"Прошу у тебя прощения за резкое слово.","vi":"Tôi xin bạn tha thứ cho lời nói cay nghiệt của tôi.","fa":"از شما می خواهم که مرا به خاطر سخنان تندم ببخشید."},{"de":"Verzeihung, ich habe Sie versehentlich angestoßen.","en":"Excuse me, I bumped into you by accident.","ru":"Извините, я случайно вас толкнул.","vi":"Xin lỗi, tôi vô tình va vào bạn.","fa":"ببخشید تصادفا با شما برخورد کردم"}]},{"word":"der Verzicht","en":"doing without; renunciation","ru":"отказ (от чего-либо)","vi":"sự từ bỏ","fa":"چشم پوشی","examples":[{"de":"Der Verzicht auf Zucker fiel ihm schwer.","en":"Giving up sugar was hard for him.","ru":"Отказ от сахара дался ему тяжело.","vi":"Rất khó để anh ấy từ bỏ đường.","fa":"ترک شکر برایش سخت بود."},{"de":"Umweltschutz bedeutet oft einen Verzicht auf Bequemlichkeit.","en":"Protecting the environment often means giving up convenience.","ru":"Охрана природы часто означает отказ от удобства.","vi":"Bảo vệ môi trường thường có nghĩa là từ bỏ sự tiện lợi.","fa":"حفاظت از محیط زیست اغلب به معنای کنار گذاشتن راحتی است."}]},{"word":"verzichten","en":"to do without, to forgo","ru":"отказываться (от чего-то)","vi":"từ bỏ","fa":"چشم پوشی","examples":[{"de":"Ich versuche, auf Zucker zu verzichten.","en":"I'm trying to do without sugar.","ru":"Я стараюсь отказаться от сахара.","vi":"Tôi đang cố gắng tránh đường.","fa":"من سعی می کنم از شکر اجتناب کنم."},{"de":"Er hat auf seinen Urlaub verzichtet, um zu arbeiten.","en":"He forwent his vacation in order to work.","ru":"Он отказался от отпуска, чтобы работать.","vi":"Anh ấy đã bỏ kỳ nghỉ của mình để đi làm.","fa":"او مرخصی خود را رها کرد تا کار کند."}]},{"word":"verzweifeln","en":"to despair","ru":"отчаиваться, приходить в отчаяние","vi":"tuyệt vọng","fa":"ناامیدی","examples":[{"de":"Du musst nicht gleich verzweifeln.","en":"You don't have to despair straight away.","ru":"Тебе не нужно сразу отчаиваться.","vi":"Bạn không cần phải tuyệt vọng ngay lập tức.","fa":"لازم نیست فوراً ناامید شوید."},{"de":"An dieser Aufgabe könnte man verzweifeln.","en":"This task could make you despair.","ru":"От этой задачи можно прийти в отчаяние.","vi":"Người ta có thể tuyệt vọng về nhiệm vụ này.","fa":"می توان از این کار ناامید شد."},{"de":"Sie verzweifelte fast an dem Problem.","en":"She almost despaired over the problem.","ru":"Она чуть не отчаялась из-за этой проблемы.","vi":"Cô gần như tuyệt vọng về vấn đề này.","fa":"او تقریباً از این مشکل ناامید شد."}]},{"word":"verzweifelt","en":"desperate, in despair","ru":"отчаявшийся, в отчаянии; отчаянный","vi":"tuyệt vọng","fa":"ناامید","examples":[{"de":"Sie suchte verzweifelt nach ihrem Schlüssel.","en":"She searched desperately for her key.","ru":"Она отчаянно искала свой ключ.","vi":"Cô tuyệt vọng tìm kiếm chìa khóa của mình.","fa":"او ناامیدانه دنبال کلیدش گشت."},{"de":"Nach der schlechten Nachricht war er völlig verzweifelt.","en":"After the bad news he was utterly in despair.","ru":"После плохой новости он был в полном отчаянии.","vi":"Sau tin dữ đó, anh ấy hoàn toàn tuyệt vọng.","fa":"پس از خبر بد، او کاملاً ناامید بود."},{"de":"Verzweifelt rief sie um Hilfe.","en":"In despair she called for help.","ru":"В отчаянии она звала на помощь.","vi":"Cô tuyệt vọng kêu cứu.","fa":"او ناامیدانه درخواست کمک کرد."}]},{"word":"das Video","en":"video","ru":"видео","vi":"đoạn video","fa":"ویدئو","examples":[{"de":"Ich habe ein lustiges Video im Internet gesehen.","en":"I saw a funny video on the internet.","ru":"Я посмотрел смешное видео в интернете.","vi":"Tôi thấy một video hài hước trên internet.","fa":"من یک ویدیوی خنده دار در اینترنت دیدم."},{"de":"Sie hat ein Video von der Hochzeit gemacht.","en":"She made a video of the wedding.","ru":"Она сняла видео со свадьбы.","vi":"Cô ấy đã quay video đám cưới.","fa":"او از عروسی فیلم گرفت."}]},{"word":"Vielen Dank für eure Aufmerksamkeit","en":"Thank you for your attention (closing a presentation)","ru":"Спасибо за внимание (завершение презентации)","vi":"Cảm ơn bạn đã quan tâm","fa":"از توجه شما متشکرم","examples":[{"de":"Vielen Dank für eure Aufmerksamkeit.","en":"Thank you for your attention.","ru":"Спасибо за внимание.","vi":"Cảm ơn bạn rất nhiều vì sự quan tâm của bạn.","fa":"از توجه شما بسیار سپاسگزارم."}]},{"word":"die Vielfalt","en":"diversity","ru":"многообразие, разнообразие","vi":"sự đa dạng","fa":"تنوع","examples":[{"de":"Die kulturelle Vielfalt der Stadt ist beeindruckend.","en":"The cultural diversity of the city is impressive.","ru":"Культурное многообразие города впечатляет.","vi":"Sự đa dạng văn hóa của thành phố thật ấn tượng.","fa":"تنوع فرهنگی این شهر چشمگیر است."},{"de":"Vielfalt macht eine Gesellschaft stärker.","en":"Diversity makes a society stronger.","ru":"Многообразие делает общество сильнее.","vi":"Sự đa dạng làm cho xã hội mạnh mẽ hơn.","fa":"تنوع جامعه را قوی تر می کند."},{"de":"In dieser Schule wird Vielfalt als Chance gesehen.","en":"At this school diversity is seen as an opportunity.","ru":"В этой школе разнообразие видят как шанс.","vi":"Ở ngôi trường này, sự đa dạng được coi là một cơ hội.","fa":"در این مکتب به تنوع به عنوان یک فرصت نگاه می شود."}]},{"word":"vielleicht","en":"maybe, perhaps","ru":"может быть, возможно","vi":"có lẽ","fa":"شاید","examples":[{"de":"Vielleicht komme ich morgen zu Besuch.","en":"Maybe I'll come to visit tomorrow.","ru":"Может быть, я приду в гости завтра.","vi":"Có lẽ ngày mai tôi sẽ đến thăm.","fa":"شاید فردا بیام دیدار"},{"de":"Er ist vielleicht schon zu Hause.","en":"Perhaps he's already at home.","ru":"Возможно, он уже дома.","vi":"Có thể anh ấy đã về nhà rồi.","fa":"او ممکن است قبلاً در خانه باشد."}]},{"word":"viel/viele","en":"much / many","ru":"много","vi":"nhiều / nhiều","fa":"زیاد/خیلی","examples":[{"de":"Ich habe heute viel Arbeit.","en":"I have a lot of work today.","ru":"У меня сегодня много работы.","vi":"Hôm nay tôi có rất nhiều việc.","fa":"امروز خیلی کار دارم."},{"de":"Auf dem Fest waren viele Gäste.","en":"There were many guests at the party.","ru":"На празднике было много гостей.","vi":"Có rất nhiều khách mời tại lễ hội.","fa":"مهمانان زیادی در این جشنواره حضور داشتند."}]},{"word":"das Viertel","en":"quarter; district, neighborhood","ru":"четверть; квартал (района)","vi":"quý","fa":"ربع","examples":[{"de":"Es ist Viertel nach neun.","en":"It's a quarter past nine.","ru":"Сейчас четверть десятого.","vi":"Bây giờ là chín giờ mười lăm.","fa":"ساعت نه و ربع است"},{"de":"Wir wohnen in einem ruhigen Viertel der Stadt.","en":"We live in a quiet district of the city.","ru":"Мы живём в тихом квартале города.","vi":"Chúng tôi sống ở một khu vực yên tĩnh của thành phố.","fa":"ما در یک منطقه آرام از شهر زندگی می کنیم."}]},{"word":"virtuell","en":"virtual","ru":"виртуальный","vi":"ảo","fa":"مجازی","examples":[{"de":"Die Ausstellung kann man auch virtuell besuchen.","en":"The exhibition can also be visited virtually.","ru":"Выставку можно посетить также виртуально.","vi":"Bạn cũng có thể tham quan triển lãm ảo.","fa":"همچنین می توانید به صورت مجازی از نمایشگاه دیدن کنید."},{"de":"Er hat viele Freunde in der virtuellen Welt der Spiele.","en":"He has many friends in the virtual world of games.","ru":"У него много друзей в виртуальном мире игр.","vi":"Anh ấy có nhiều bạn bè trong thế giới ảo của trò chơi.","fa":"او در دنیای مجازی بازی دوستان زیادی دارد."}]},{"word":"der Virus","en":"virus","ru":"вирус","vi":"virus","fa":"ویروس","examples":[{"de":"Ein Virus hat meinen Computer infiziert.","en":"A virus infected my computer.","ru":"Вирус заразил мой компьютер.","vi":"Một loại virus đã lây nhiễm vào máy tính của tôi.","fa":"یک ویروس کامپیوتر من را آلوده کرده است."},{"de":"Der Arzt vermutet, dass sie sich mit einem Virus angesteckt hat.","en":"The doctor suspects that she caught a virus.","ru":"Врач предполагает, что она заразилась вирусом.","vi":"Bác sĩ nghi ngờ cô đã bị nhiễm virus.","fa":"دکتر مشکوک است که او به ویروس آلوده شده است."}]},{"word":"die Visitenkarte","en":"business card","ru":"визитная карточка","vi":"thẻ kinh doanh","fa":"کارت ویزیت","examples":[{"de":"Er gab mir seine Visitenkarte nach dem Gespräch.","en":"He gave me his business card after the conversation.","ru":"После разговора он дал мне свою визитку.","vi":"Anh ấy đưa cho tôi danh thiếp của anh ấy sau cuộc trò chuyện.","fa":"بعد از صحبت کارت ویزیتش را به من داد."},{"de":"Auf der Visitenkarte stehen seine Telefonnummer und E-Mail-Adresse.","en":"His phone number and email address are on the business card.","ru":"На визитке указаны его номер телефона и электронная почта.","vi":"Số điện thoại và địa chỉ email của anh ấy có trên danh thiếp.","fa":"شماره تلفن و آدرس ایمیل او در کارت ویزیت موجود است."}]},{"word":"das Visum","en":"visa","ru":"виза","vi":"thị thực","fa":"ویزا","examples":[{"de":"Für die Reise nach Russland brauche ich ein Visum.","en":"I need a visa for the trip to Russia.","ru":"Для поездки в Россию мне нужна виза.","vi":"Tôi cần visa để đi du lịch đến Nga.","fa":"برای سفر به روسیه به ویزا نیاز دارم."},{"de":"Das Visum wurde für drei Monate ausgestellt.","en":"The visa was issued for three months.","ru":"Виза была выдана на три месяца.","vi":"Thị thực đã được cấp trong ba tháng.","fa":"ویزا برای سه ماه صادر شد."}]},{"word":"das Vitamin","en":"vitamin","ru":"витамин","vi":"vitamin","fa":"ویتامین","examples":[{"de":"Orangen enthalten viel Vitamin C.","en":"Oranges contain a lot of vitamin C.","ru":"Апельсины содержат много витамина С.","vi":"Cam chứa rất nhiều vitamin C.","fa":"پرتقال حاوی مقدار زیادی ویتامین C است."},{"de":"Im Winter nehme ich manchmal Vitamintabletten.","en":"In winter I sometimes take vitamin tablets.","ru":"Зимой я иногда принимаю витаминные таблетки.","vi":"Vào mùa đông thỉnh thoảng tôi uống viên vitamin.","fa":"در زمستان گاهی قرص ویتامین مصرف می کنم."}]},{"word":"vitaminreich","en":"rich in vitamins","ru":"богатый витаминами","vi":"giàu vitamin","fa":"سرشار از ویتامین","examples":[{"de":"Obst und Gemüse sind besonders vitaminreich.","en":"Fruit and vegetables are especially rich in vitamins.","ru":"Фрукты и овощи особенно богаты витаминами.","vi":"Trái cây và rau quả đặc biệt giàu vitamin.","fa":"میوه ها و سبزیجات به ویژه سرشار از ویتامین هستند."},{"de":"Eine vitaminreiche Ernährung hält dich gesund.","en":"A vitamin-rich diet keeps you healthy.","ru":"Богатое витаминами питание сохраняет здоровье.","vi":"Một chế độ ăn giàu vitamin giúp bạn khỏe mạnh.","fa":"رژیم غذایی سرشار از ویتامین شما را سالم نگه می دارد."},{"de":"Der Arzt empfahl mir vitaminreiches Essen.","en":"The doctor recommended vitamin-rich food to me.","ru":"Врач порекомендовал мне богатую витаминами пищу.","vi":"Bác sĩ khuyên nên ăn thực phẩm giàu vitamin.","fa":"دکتر غذای غنی از ویتامین را توصیه کرد."}]},{"word":"der Volkstanz","en":"folk dance","ru":"народный танец","vi":"điệu múa dân gian","fa":"رقص محلی","examples":[{"de":"Auf dem Fest führten sie einen alten Volkstanz auf.","en":"At the festival they performed an old folk dance.","ru":"На фестивале исполнили старинный народный танец.","vi":"Tại lễ hội họ biểu diễn một điệu múa dân gian cổ xưa.","fa":"در جشنواره یک رقص محلی قدیمی اجرا کردند."},{"de":"Jede Region hat ihre eigenen Volkstänze.","en":"Every region has its own folk dances.","ru":"В каждом регионе свои народные танцы.","vi":"Mỗi vùng có những điệu múa dân gian riêng.","fa":"هر منطقه رقص های محلی خود را دارد."},{"de":"Der Volkstanz wird oft in Tracht getanzt.","en":"The folk dance is often danced in traditional costume.","ru":"Народный танец часто танцуют в национальном костюме.","vi":"Múa dân gian thường được thực hiện trong trang phục truyền thống.","fa":"رقص محلی اغلب با لباس سنتی انجام می شود."}]},{"word":"voll","en":"full","ru":"полный","vi":"đầy đủ","fa":"کامل","examples":[{"de":"Der Bus war so voll, dass ich stehen musste.","en":"The bus was so full that I had to stand.","ru":"Автобус был настолько полным, что мне пришлось стоять.","vi":"Xe buýt đông đến mức tôi phải đứng.","fa":"اتوبوس آنقدر پر بود که مجبور شدم بایستم."},{"de":"Das Glas ist bis zum Rand voll.","en":"The glass is full to the brim.","ru":"Стакан полон до краёв.","vi":"Kính đã đầy tới miệng.","fa":"لیوان تا لبه پر است."}]},{"word":"Volleyball","en":"volleyball","ru":"волейбол","vi":"bóng chuyền","fa":"والیبال","examples":[{"de":"Am Strand spielen wir gern Volleyball.","en":"We like playing volleyball at the beach.","ru":"На пляже мы любим играть в волейбол.","vi":"Chúng tôi thích chơi bóng chuyền trên bãi biển.","fa":"ما دوست داریم در ساحل والیبال بازی کنیم."},{"de":"Sie ist Mitglied im Volleyball-Verein.","en":"She is a member of the volleyball club.","ru":"Она состоит в волейбольном клубе.","vi":"Cô là thành viên của câu lạc bộ bóng chuyền.","fa":"او عضو باشگاه والیبال است."}]},{"word":"völlig","en":"completely","ru":"полностью, совершенно","vi":"hoàn toàn","fa":"به طور کامل","examples":[{"de":"Das ist mir völlig egal.","en":"That's completely irrelevant to me.","ru":"Мне это совершенно всё равно.","vi":"Tôi không quan tâm chút nào.","fa":"اصلا برام مهم نیست"},{"de":"Nach dem Marathon war er völlig erschöpft.","en":"After the marathon he was completely exhausted.","ru":"После марафона он был совершенно измотан.","vi":"Sau cuộc chạy marathon, anh ấy hoàn toàn kiệt sức.","fa":"پس از ماراتن او کاملا خسته بود."}]},{"word":"der Vollmond","en":"full moon","ru":"полнолуние","vi":"trăng tròn","fa":"ماه کامل","examples":[{"de":"Heute Nacht ist Vollmond, der Himmel ist ganz hell.","en":"Tonight is a full moon, the sky is very bright.","ru":"Сегодня ночью полнолуние, небо совсем светлое.","vi":"Đêm nay trăng tròn và bầu trời rất sáng.","fa":"امشب ماه کامل است و آسمان بسیار روشن است."},{"de":"Bei Vollmond kann ich oft schlechter schlafen.","en":"During a full moon I often sleep worse.","ru":"В полнолуние я часто хуже сплю.","vi":"Tôi thường khó ngủ hơn khi trăng tròn.","fa":"اغلب وقتی ماه کامل است خوابیدن برایم سخت تر است."},{"de":"Der Vollmond spiegelte sich im ruhigen Wasser.","en":"The full moon was reflected in the calm water.","ru":"Полная луна отражалась в спокойной воде.","vi":"Trăng tròn phản chiếu trên mặt nước tĩnh lặng.","fa":"ماه کامل در آب آرام منعکس شد."}]},{"word":"die Vollzeit","en":"full-time work","ru":"полная занятость, работа на полную ставку","vi":"toàn thời gian","fa":"تمام وقت","examples":[{"de":"Ich arbeite Vollzeit und habe kaum noch Freizeit.","en":"I work full-time and have hardly any free time left.","ru":"Я работаю на полную ставку, и свободного времени почти не остаётся.","vi":"Tôi làm việc toàn thời gian và hầu như không có thời gian rảnh.","fa":"من تمام وقت کار می کنم و به سختی وقت آزاد دارم."},{"de":"Die Stelle ist nur in Vollzeit zu besetzen.","en":"The position can only be filled full-time.","ru":"Эту должность можно занять только на полную ставку.","vi":"Vị trí này chỉ có thể được lấp đầy toàn thời gian.","fa":"این موقعیت فقط به صورت تمام وقت قابل پر شدن است."},{"de":"Nach dem Studium hat er sofort eine Vollzeitstelle gefunden.","en":"After his degree he immediately found a full-time job.","ru":"После учёбы он сразу нашёл работу на полную ставку.","vi":"Sau khi hoàn thành việc học, anh ngay lập tức tìm được một công việc toàn thời gian.","fa":"پس از اتمام تحصیلاتش، بلافاصله شغلی تمام وقت پیدا کرد."}]},{"word":"die Vollzeitstelle","en":"full-time job","ru":"работа на полную ставку, полная занятость","vi":"vị trí toàn thời gian","fa":"موقعیت تمام وقت","examples":[{"de":"Sie sucht eine Vollzeitstelle in einem Büro.","en":"She is looking for a full-time job in an office.","ru":"Она ищет работу на полную ставку в офисе.","vi":"Cô ấy đang tìm kiếm một vị trí toàn thời gian trong một văn phòng.","fa":"او به دنبال یک موقعیت تمام وقت در یک دفتر است."},{"de":"Nach dem Studium fand er sofort eine Vollzeitstelle.","en":"After his studies he found a full-time job straight away.","ru":"После учёбы он сразу нашёл работу на полную ставку.","vi":"Sau khi hoàn thành việc học, anh ngay lập tức tìm được một công việc toàn thời gian.","fa":"پس از اتمام تحصیلاتش، بلافاصله شغلی تمام وقت پیدا کرد."},{"de":"Eine Vollzeitstelle umfasst meist vierzig Stunden pro Woche.","en":"A full-time job usually involves forty hours a week.","ru":"Полная ставка обычно предполагает сорок часов в неделю.","vi":"Một vị trí toàn thời gian thường bao gồm bốn mươi giờ mỗi tuần.","fa":"یک موقعیت تمام وقت معمولاً شامل چهل ساعت در هفته است."}]},{"word":"das Volumen","en":"volume","ru":"объём","vi":"âm lượng","fa":"حجم","examples":[{"de":"Das Volumen eines Würfels ist Kante mal Kante mal Kante.","en":"The volume of a cube is edge times edge times edge.","ru":"Объём куба — это ребро, умноженное на ребро и ещё раз на ребро.","vi":"Thể tích của hình lập phương là cạnh nhân cạnh nhân cạnh.","fa":"حجم یک مکعب یال ضربدر لبه است."},{"de":"Die Flasche hat ein Volumen von einem Liter.","en":"The bottle has a volume of one litre.","ru":"У бутылки объём один литр.","vi":"Chai có thể tích một lít.","fa":"حجم بطری یک لیتر است."},{"de":"Wir berechneten das Volumen des Behälters.","en":"We calculated the volume of the container.","ru":"Мы вычислили объём контейнера.","vi":"Chúng tôi đã tính toán khối lượng của container.","fa":"حجم ظرف را محاسبه کردیم."}]},{"word":"von","en":"from, of, by","ru":"от, из, о","vi":"từ","fa":"از","examples":[{"de":"Dieses Geschenk ist von meiner Mutter.","en":"This gift is from my mother.","ru":"Этот подарок от моей матери.","vi":"Món quà này là của mẹ tôi.","fa":"این هدیه از طرف مادرم است."},{"de":"Der Roman wurde von einem berühmten Autor geschrieben.","en":"The novel was written by a famous author.","ru":"Роман был написан известным автором.","vi":"Cuốn tiểu thuyết được viết bởi một tác giả nổi tiếng.","fa":"این رمان توسط یک نویسنده مشهور نوشته شده است."}]},{"word":"Von mir aus","en":"Fine by me (reluctant agreement)","ru":"По мне так ладно / Не возражаю (согласие без энтузиазма)","vi":"Tôi ổn thôi","fa":"از من خوبه","examples":[{"de":"Von mir aus können wir auch später gehen.","en":"Fine by me, we can also go later.","ru":"По мне так можно пойти и позже.","vi":"Theo như tôi được biết, chúng ta có thể đi sau.","fa":"تا جایی که به من مربوط می شود، می توانیم بعداً برویم."}]},{"word":"voneinander","en":"from each other, of each other","ru":"друг от друга, друг о друге","vi":"từ nhau","fa":"از یکدیگر","examples":[{"de":"Die Freunde haben lange nichts voneinander gehört.","en":"The friends hadn't heard from each other for a long time.","ru":"Друзья долго ничего не слышали друг о друге.","vi":"Bạn bè đã lâu không liên lạc với nhau.","fa":"دوستان مدت زیادی است که از یکدیگر خبری ندارند."},{"de":"Die Zwillinge sind kaum voneinander zu unterscheiden.","en":"The twins can hardly be distinguished from each other.","ru":"Близнецов едва можно отличить друг от друга.","vi":"Cặp song sinh khó có thể phân biệt được với nhau.","fa":"دوقلوها را به سختی می توان از یکدیگر تشخیص داد."}]},{"word":"vor","en":"before, in front of, ago","ru":"перед, до, назад (о времени)","vi":"trước đây","fa":"قبل از","examples":[{"de":"Das Auto steht vor dem Haus.","en":"The car is parked in front of the house.","ru":"Машина стоит перед домом.","vi":"Ôtô đậu trước nhà.","fa":"ماشین جلوی خانه است."},{"de":"Vor zwei Jahren habe ich meinen Job gewechselt.","en":"Two years ago I changed my job.","ru":"Два года назад я сменил работу.","vi":"Hai năm trước tôi đã thay đổi công việc của mình.","fa":"دو سال پیش شغلم را عوض کردم."}]},{"word":"vor allem","en":"above all, especially","ru":"прежде всего, особенно","vi":"trên hết","fa":"بالاتر از همه","examples":[{"de":"Ich mag Obst, vor allem Erdbeeren.","en":"I like fruit, especially strawberries.","ru":"Я люблю фрукты, особенно клубнику.","vi":"Tôi thích trái cây, đặc biệt là dâu tây.","fa":"من میوه مخصوصا توت فرنگی دوست دارم."},{"de":"Vor allem im Sommer trinke ich viel Wasser.","en":"Above all in summer I drink a lot of water.","ru":"Прежде всего летом я пью много воды.","vi":"Tôi uống rất nhiều nước, đặc biệt là vào mùa hè.","fa":"من زیاد آب میخورم مخصوصا در تابستان."},{"de":"Es geht vor allem um die Sicherheit der Kinder.","en":"It is above all about the safety of the children.","ru":"Речь идёт прежде всего о безопасности детей.","vi":"Tất cả đều vì sự an toàn của trẻ em.","fa":"همه چیز در مورد ایمنی کودکان است."}]},{"word":"voraus","en":"ahead, in advance","ru":"заранее, вперёд","vi":"phía trước","fa":"جلوتر","examples":[{"de":"Vielen Dank im Voraus für Ihre Hilfe.","en":"Thank you in advance for your help.","ru":"Заранее спасибо за вашу помощь.","vi":"Cảm ơn bạn trước sự giúp đỡ của bạn.","fa":"پیشاپیش از کمک شما سپاسگزارم."},{"de":"Er ist seiner Zeit weit voraus.","en":"He is far ahead of his time.","ru":"Он далеко опережает своё время.","vi":"Anh ấy đã đi trước thời đại rất nhiều.","fa":"او بسیار جلوتر از زمان خود است."}]},{"word":"die Voraussage","en":"prediction, forecast","ru":"предсказание, прогноз","vi":"dự đoán","fa":"پیش بینی","examples":[{"de":"Die Voraussage für morgen verspricht Sonne.","en":"The forecast for tomorrow promises sun.","ru":"Прогноз на завтра обещает солнце.","vi":"Dự báo ngày mai hứa hẹn sẽ có nắng.","fa":"پیش بینی فردا نوید آفتاب را می دهد."},{"de":"Seine Voraussage hat sich bewahrheitet.","en":"His prediction came true.","ru":"Его предсказание сбылось.","vi":"Dự đoán của ông đã thành sự thật.","fa":"پیش بینی او به حقیقت پیوست."},{"de":"Eine genaue Voraussage ist hier schwierig.","en":"An exact prediction is difficult here.","ru":"Точный прогноз здесь затруднителен.","vi":"Một dự đoán chính xác là khó khăn ở đây.","fa":"پیش‌بینی دقیق در اینجا دشوار است."}]},{"word":"voraussetzen","en":"to presuppose; to require","ru":"предполагать; требовать (как условие)","vi":"giả sử","fa":"فرض کنید","examples":[{"de":"Diese Aufgabe setzt gute Vorkenntnisse voraus.","en":"This task requires good prior knowledge.","ru":"Это задание требует хороших предварительных знаний.","vi":"Nhiệm vụ này đòi hỏi kiến thức tốt trước đó.","fa":"این کار مستلزم دانش قبلی خوب است."},{"de":"Ich setze voraus, dass alle pünktlich sind.","en":"I assume that everyone will be on time.","ru":"Я исхожу из того, что все будут вовремя.","vi":"Tôi cho rằng mọi người đều đúng giờ.","fa":"من فرض می کنم که همه به موقع هستند."}]},{"word":"die Voraussetzung","en":"prerequisite, requirement","ru":"предпосылка, условие","vi":"điều kiện tiên quyết","fa":"پیش نیاز","examples":[{"de":"Gute Deutschkenntnisse sind Voraussetzung für diesen Job.","en":"Good German skills are a prerequisite for this job.","ru":"Хорошее знание немецкого языка — обязательное условие для этой работы.","vi":"Kiến thức tốt về tiếng Đức là điều kiện tiên quyết cho công việc này.","fa":"آشنایی با زبان آلمانی پیش نیاز این شغل می باشد."},{"de":"Welche Voraussetzungen muss ich für das Studium erfüllen?","en":"What requirements do I need to meet for the studies?","ru":"Каким требованиям я должен соответствовать для обучения?","vi":"Tôi phải đáp ứng những yêu cầu gì để học?","fa":"برای تحصیل چه شرایطی را باید رعایت کنم؟"}]},{"word":"voraussichtlich","en":"probably, expected (to happen)","ru":"предположительно, ожидаемо","vi":"dự kiến","fa":"انتظار می رود","examples":[{"de":"Der Flug landet voraussichtlich um 18 Uhr.","en":"The flight is expected to land at 6 p.m.","ru":"Самолёт предположительно приземлится в 18:00.","vi":"Dự kiến chuyến bay sẽ hạ cánh lúc 18h.","fa":"انتظار می رود این پرواز ساعت 6 بعد از ظهر به زمین بنشیند."},{"de":"Die Bauarbeiten werden voraussichtlich im Herbst fertig.","en":"The construction work is expected to be finished in autumn.","ru":"Строительные работы предположительно завершатся осенью.","vi":"Công việc xây dựng dự kiến ​​sẽ hoàn thành vào mùa thu.","fa":"انتظار می رود کار ساخت و ساز در پاییز به پایان برسد."}]},{"word":"vorbei","en":"past, over, by","ru":"мимо, окончен(о)","vi":"kết thúc","fa":"تمام","examples":[{"de":"Der Sommer ist schon vorbei.","en":"Summer is already over.","ru":"Лето уже прошло.","vi":"Mùa hè đã kết thúc rồi.","fa":"تابستان دیگر تمام شده است."},{"de":"Er lief schnell an mir vorbei.","en":"He ran quickly past me.","ru":"Он быстро пробежал мимо меня.","vi":"Anh ấy nhanh chóng chạy qua tôi.","fa":"سریع از کنارم رد شد."}]},{"word":"vorbei-","en":"past, by (separable prefix: vorbeikommen, vorbeigehen)","ru":"мимо (отделяемая приставка: vorbeikommen — заходить, vorbeigehen — проходить мимо)","vi":"hơn-","fa":"بیش از حد","examples":[{"de":"Komm doch heute Abend bei uns vorbei.","en":"Why not come by our place this evening.","ru":"Зайди же к нам сегодня вечером.","vi":"Hãy đến gặp chúng tôi tối nay.","fa":"امروز عصر بیا و ما را ببین"},{"de":"Wir sind an dem alten Schloss vorbeigefahren.","en":"We drove past the old castle.","ru":"Мы проехали мимо старого замка.","vi":"Chúng tôi lái xe qua lâu đài cổ.","fa":"از کنار قلعه قدیمی رد شدیم."},{"de":"Der Sommer ist leider schon wieder vorbei.","en":"Unfortunately the summer is already over again.","ru":"К сожалению, лето снова уже прошло.","vi":"Thật không may, mùa hè đã kết thúc.","fa":"متاسفانه تابستان تمام شده است."}]},{"word":"vorbereiten","en":"to prepare","ru":"готовить, подготавливать","vi":"chuẩn bị","fa":"آماده کنید","examples":[{"de":"Am Abend bereite ich schon das Essen für morgen vor.","en":"In the evening I prepare the meal for tomorrow in advance.","ru":"Вечером я заранее готовлю еду на завтра.","vi":"Buổi tối tôi chuẩn bị bữa tối cho ngày mai.","fa":"عصر برای فردا شام آماده می کنم."},{"de":"Ich muss mich noch auf die Prüfung vorbereiten.","en":"I still have to prepare for the exam.","ru":"Мне ещё нужно подготовиться к экзамену.","vi":"Tôi vẫn phải chuẩn bị cho kỳ thi.","fa":"هنوز باید برای امتحان آماده شوم."},{"de":"Sie hat alles für die Feier sorgfältig vorbereitet.","en":"She carefully prepared everything for the party.","ru":"Она тщательно подготовила всё к празднику.","vi":"Cô chuẩn bị cẩn thận mọi thứ cho lễ kỷ niệm.","fa":"او با دقت همه چیز را برای جشن آماده کرد."}]},{"word":"vorbereitet","en":"prepared, ready","ru":"подготовленный, готовый","vi":"chuẩn bị sẵn sàng","fa":"آماده شده است","examples":[{"de":"Ich bin gut auf die Prüfung vorbereitet.","en":"I am well prepared for the exam.","ru":"Я хорошо подготовлен к экзамену.","vi":"Tôi đang chuẩn bị tốt cho kỳ thi.","fa":"من به خوبی برای امتحان آماده هستم."},{"de":"Auf so eine Frage war ich nicht vorbereitet.","en":"I was not prepared for a question like that.","ru":"К такому вопросу я не был готов.","vi":"Tôi chưa chuẩn bị cho một câu hỏi như thế.","fa":"من برای چنین سوالی آماده نبودم."},{"de":"Das Essen ist schon vorbereitet, wir können gleich anfangen.","en":"The meal is already prepared, we can start straight away.","ru":"Еда уже приготовлена, можем сразу начинать.","vi":"Thức ăn đã được chuẩn bị sẵn, chúng ta có thể bắt đầu ngay.","fa":"غذا از قبل آماده شده است، می توانیم بلافاصله شروع کنیم."}]},{"word":"die Vorbereitung","en":"preparation","ru":"подготовка","vi":"sự chuẩn bị","fa":"آماده سازی","examples":[{"de":"Die Vorbereitung auf die Prüfung dauerte mehrere Wochen.","en":"The preparation for the exam took several weeks.","ru":"Подготовка к экзамену заняла несколько недель.","vi":"Việc chuẩn bị cho kỳ thi mất vài tuần.","fa":"آماده شدن برای امتحان چند هفته طول کشید."},{"de":"Ohne gute Vorbereitung wird die Reise stressig.","en":"Without good preparation the trip will be stressful.","ru":"Без хорошей подготовки поездка будет напряжённой.","vi":"Nếu không có sự chuẩn bị tốt, chuyến đi sẽ rất căng thẳng.","fa":"بدون آمادگی خوب، سفر پر استرس خواهد بود."},{"de":"Die Vorbereitungen für das Fest laufen auf Hochtouren.","en":"The preparations for the party are in full swing.","ru":"Подготовка к вечеринке в самом разгаре.","vi":"Công tác chuẩn bị cho lễ hội đang được gấp rút hoàn thành.","fa":"آماده سازی جشنواره در حال انجام است."}]},{"word":"die Vorbeuge","en":"forward bend","ru":"наклон вперёд","vi":"phòng ngừa","fa":"پیشگیری","examples":[{"de":"In der Vorbeuge lässt du den Kopf locker hängen.","en":"In the forward bend you let your head hang loosely.","ru":"В наклоне вперёд ты свободно опускаешь голову.","vi":"Khi cúi về phía trước, hãy để đầu bạn thả lỏng.","fa":"هنگام خم شدن به جلو، اجازه دهید سر خود را آزادانه آویزان کنید."},{"de":"Die stehende Vorbeuge dehnt die Rückseite der Beine.","en":"The standing forward bend stretches the backs of the legs.","ru":"Наклон вперёд стоя растягивает заднюю поверхность ног.","vi":"Tư thế đứng gập người về phía trước kéo dãn phần sau của chân.","fa":"خم شدن به جلو ایستاده، پشت پاها را دراز می کند."},{"de":"Beuge die Knie leicht, wenn die Vorbeuge zu schwer ist.","en":"Bend your knees slightly if the forward bend is too hard.","ru":"Слегка согни колени, если наклон вперёд даётся тяжело.","vi":"Cong đầu gối của bạn một chút nếu việc cúi về phía trước quá khó khăn.","fa":"اگر خم شدن به جلو خیلی سخت است، زانوهای خود را کمی خم کنید."}]},{"word":"vorder","en":"front, fore (attributive)","ru":"передний (в качестве определения)","vi":"phía trước","fa":"جلو","examples":[{"de":"Wir saßen in der vorderen Reihe des Kinos.","en":"We sat in the front row of the cinema.","ru":"Мы сидели в переднем ряду кинотеатра.","vi":"Chúng tôi ngồi ở hàng ghế đầu của rạp chiếu phim.","fa":"در ردیف اول سینما نشستیم."},{"de":"Der vordere Reifen ist platt.","en":"The front tyre is flat.","ru":"Переднее колесо спущено.","vi":"Lốp trước bị xẹp.","fa":"لاستیک جلو صاف است."},{"de":"Bitte benutzen Sie die vordere Tür zum Aussteigen.","en":"Please use the front door to get off.","ru":"Пожалуйста, используйте переднюю дверь для выхода.","vi":"Vui lòng sử dụng cửa trước để thoát ra.","fa":"لطفا از درب جلو برای خروج استفاده کنید."}]},{"word":"vorder-","en":"front- (prefix meaning 'front')","ru":"передний- (приставка)","vi":"phía trước","fa":"جلو","examples":[{"de":"Bitte setzen Sie sich auf den Vordersitz.","en":"Please sit in the front seat.","ru":"Пожалуйста, садитесь на переднее сиденье.","vi":"Xin vui lòng ngồi ở ghế trước.","fa":"لطفا روی صندلی جلو بنشینید"},{"de":"Die Vordertür des Hauses war abgeschlossen.","en":"The front door of the house was locked.","ru":"Входная дверь дома была заперта.","vi":"Cửa trước của ngôi nhà đã bị khóa.","fa":"درب ورودی خانه قفل بود."}]},{"word":"das Vorderlicht","en":"front light (e.g. on a bicycle)","ru":"передняя фара (например, на велосипеде)","vi":"ánh sáng phía trước","fa":"چراغ جلو","examples":[{"de":"Das Vorderlicht meines Fahrrads ist kaputt.","en":"The front light on my bicycle is broken.","ru":"Передняя фара на моём велосипеде сломана.","vi":"Đèn trước trên xe đạp của tôi bị hỏng.","fa":"چراغ جلوی دوچرخه من خراب است."},{"de":"Bei Dunkelheit muss das Vorderlicht eingeschaltet sein.","en":"In the dark the front light must be switched on.","ru":"В темноте передняя фара должна быть включена.","vi":"Đèn phía trước phải được bật trong bóng tối.","fa":"چراغ جلو باید در تاریکی روشن شود."},{"de":"Er hat ein neues Vorderlicht am Fahrrad montiert.","en":"He fitted a new front light to the bicycle.","ru":"Он установил на велосипед новую переднюю фару.","vi":"Anh ấy đã lắp một đèn trước mới cho chiếc xe đạp.","fa":"او یک چراغ جلوی جدید روی دوچرخه نصب کرد."}]},{"word":"die Vorfahrt","en":"right of way (traffic)","ru":"право преимущественного проезда","vi":"quyền đi đường","fa":"حق تقدم","examples":[{"de":"An dieser Kreuzung habe ich Vorfahrt.","en":"I have the right of way at this intersection.","ru":"На этом перекрёстке у меня преимущество проезда.","vi":"Tôi có quyền ưu tiên ở ngã tư này.","fa":"من در این تقاطع حق تقدم دارم."},{"de":"Er hat die Vorfahrt missachtet und fast einen Unfall verursacht.","en":"He ignored the right of way and almost caused an accident.","ru":"Он не уступил дорогу и чуть не стал причиной аварии.","vi":"Anh ta đã phớt lờ quyền ưu tiên và suýt gây ra tai nạn.","fa":"حق تقدم را نادیده گرفت و نزدیک بود تصادف کند."}]},{"word":"die Vorführung","en":"performance, demonstration","ru":"выступление, показ, демонстрация","vi":"cuộc biểu tình","fa":"تظاهرات","examples":[{"de":"Die Vorführung der Tanzgruppe war beeindruckend.","en":"The dance group's performance was impressive.","ru":"Выступление танцевальной группы было впечатляющим.","vi":"Màn biểu diễn của nhóm nhảy thật ấn tượng.","fa":"اجرای گروه رقص چشمگیر بود."},{"de":"Nach der Vorführung gab es viel Applaus.","en":"After the performance there was a lot of applause.","ru":"После выступления было много аплодисментов.","vi":"Có rất nhiều tiếng vỗ tay sau màn trình diễn.","fa":"پس از اجرا تشویق های زیادی به راه افتاد."},{"de":"Die Vorführung beginnt um acht Uhr.","en":"The performance begins at eight o'clock.","ru":"Выступление начинается в восемь часов.","vi":"Buổi biểu diễn bắt đầu lúc tám giờ.","fa":"اجرا از ساعت هشت شروع می شود."}]},{"word":"vorgeschrieben","en":"prescribed, required, mandatory","ru":"предписанный, обязательный","vi":"quy định","fa":"تجویز شده است","examples":[{"de":"Auf dieser Straße ist eine Geschwindigkeit von fünfzig vorgeschrieben.","en":"On this road a speed of fifty is mandatory.","ru":"На этой дороге предписана скорость пятьдесят.","vi":"Giới hạn tốc độ trên con đường này là năm mươi.","fa":"سرعت مجاز در این جاده پنجاه است."},{"de":"Der vorgeschriebene Helm muss immer getragen werden.","en":"The prescribed helmet must always be worn.","ru":"Предписанный шлем нужно всегда носить.","vi":"Phải luôn đội mũ bảo hiểm bắt buộc.","fa":"کلاه ایمنی مورد نیاز باید همیشه استفاده شود."},{"de":"Es gibt eine vorgeschriebene Form für den Antrag.","en":"There is a prescribed form for the application.","ru":"Для заявления есть предписанная форма.","vi":"Có mẫu đơn quy định.","fa":"یک فرم تجویز شده برای درخواست وجود دارد."}]},{"word":"vorgestern","en":"the day before yesterday","ru":"позавчера","vi":"ngày hôm kia","fa":"پریروز","examples":[{"de":"Vorgestern habe ich meine Großeltern besucht.","en":"I visited my grandparents the day before yesterday.","ru":"Позавчера я навещал своих бабушку и дедушку.","vi":"Hôm kia tôi đến thăm ông bà tôi.","fa":"دیروز به پدربزرگ و مادربزرگم سر زدم."},{"de":"Das Paket ist schon vorgestern angekommen.","en":"The package already arrived the day before yesterday.","ru":"Посылка уже пришла позавчера.","vi":"Gói hàng đã đến vào ngày hôm kia.","fa":"بسته پریروز رسید."}]},{"word":"vorhaben","en":"to plan, to intend","ru":"планировать, намереваться","vi":"kế hoạch","fa":"برنامه ریزی کنید","examples":[{"de":"Was hast du am Wochenende vor?","en":"What do you have planned for the weekend?","ru":"Что ты планируешь на выходные?","vi":"Cuối tuần này bạn định làm gì?","fa":"این آخر هفته چه کاره ای؟"},{"de":"Wir haben vor, nächstes Jahr nach Japan zu reisen.","en":"We plan to travel to Japan next year.","ru":"Мы планируем поехать в Японию в следующем году.","vi":"Chúng tôi đang có kế hoạch đi du lịch Nhật Bản vào năm tới.","fa":"ما قصد داریم سال آینده به ژاپن سفر کنیم."}]},{"word":"der Vorhang","en":"curtain","ru":"штора, занавеска","vi":"bức màn","fa":"پرده","examples":[{"de":"Am Abend ziehe ich die Vorhänge zu.","en":"In the evening I close the curtains.","ru":"Вечером я задёргиваю шторы.","vi":"Buổi tối tôi kéo rèm lại.","fa":"عصر پرده ها را می بندم."},{"de":"Durch den dünnen Vorhang scheint morgens die Sonne.","en":"The sun shines through the thin curtain in the morning.","ru":"Утром солнце светит сквозь тонкую занавеску.","vi":"Buổi sáng ánh nắng xuyên qua tấm rèm mỏng.","fa":"آفتاب صبح از میان پرده نازک می تابد."},{"de":"Wir brauchen neue Vorhänge für das Wohnzimmer.","en":"We need new curtains for the living room.","ru":"Нам нужны новые шторы для гостиной.","vi":"Chúng tôi cần rèm mới cho phòng khách.","fa":"به پرده های جدید برای اتاق نشیمن نیاز داریم."}]},{"word":"vorher","en":"before, beforehand","ru":"раньше, заранее, до этого","vi":"trước đây","fa":"قبل از","examples":[{"de":"Ruf mich bitte vorher an, bevor du kommst.","en":"Please call me beforehand before you come.","ru":"Пожалуйста, позвони мне заранее, прежде чем прийти.","vi":"Hãy gọi cho tôi trước khi bạn đến.","fa":"لطفا قبل از آمدن با من تماس بگیرید."},{"de":"Ich kannte ihn schon vorher.","en":"I already knew him from before.","ru":"Я знал его ещё раньше.","vi":"Tôi biết anh ấy trước đây.","fa":"من او را قبلا می شناختم."}]},{"word":"die Vorhersage","en":"prediction, forecast","ru":"предсказание, прогноз","vi":"dự đoán","fa":"پیش بینی","examples":[{"de":"Die Vorhersage des Modells war erstaunlich genau.","en":"The model's prediction was remarkably accurate.","ru":"Предсказание модели было удивительно точным.","vi":"Dự đoán của mô hình chính xác một cách đáng ngạc nhiên.","fa":"پیش بینی مدل به طرز شگفت آوری دقیق بود."},{"de":"Die Vorhersage für morgen verspricht Sonne und milden Wind.","en":"The forecast for tomorrow promises sun and a mild breeze.","ru":"Прогноз на завтра обещает солнце и лёгкий ветер.","vi":"Dự báo ngày mai hứa hẹn nắng nhẹ và gió nhẹ.","fa":"پیش بینی فردا نوید آفتاب و وزش باد ملایم را می دهد."},{"de":"Niemand wollte seiner düsteren Vorhersage glauben.","en":"Nobody wanted to believe his gloomy prediction.","ru":"Никто не хотел верить его мрачному предсказанию.","vi":"Không ai muốn tin vào lời tiên đoán thảm khốc của anh ta.","fa":"هیچ کس نمی خواست پیش بینی وحشتناک او را باور کند."}]},{"word":"vorhin","en":"a short while ago, just now","ru":"недавно, только что","vi":"trước đó","fa":"زودتر","examples":[{"de":"Vorhin hat es noch geregnet, jetzt scheint die Sonne.","en":"It was raining just now, now the sun is shining.","ru":"Только что шёл дождь, а сейчас светит солнце.","vi":"Vừa nãy trời còn mưa, bây giờ trời đã nắng.","fa":"چند لحظه پیش باران می بارید، حالا خورشید می درخشد."},{"de":"Ich habe dich vorhin schon angerufen, aber du hast nicht abgenommen.","en":"I already called you a little while ago, but you didn't pick up.","ru":"Я уже звонил тебе недавно, но ты не ответил.","vi":"Lúc trước tôi gọi cho bạn nhưng bạn không bắt máy.","fa":"من زودتر بهت زنگ زدم اما نگرفتی"}]},{"word":"vorkommen","en":"to occur, to happen","ru":"случаться, встречаться","vi":"xảy ra","fa":"رخ دهد","examples":[{"de":"So ein Fehler darf nicht noch einmal vorkommen.","en":"Such a mistake must not happen again.","ru":"Такая ошибка не должна повториться.","vi":"Một sai lầm như thế này không được phép xảy ra lần nữa.","fa":"چنین اشتباهی نباید دوباره تکرار شود."},{"de":"Diese Pflanze kommt nur in den Bergen vor.","en":"This plant only occurs in the mountains.","ru":"Это растение встречается только в горах.","vi":"Loại cây này chỉ được tìm thấy ở vùng núi.","fa":"این گیاه فقط در کوهستان یافت می شود."}]},{"word":"vorläufig","en":"temporary, provisional, for now","ru":"временный, предварительный","vi":"tạm thời","fa":"به طور موقت","examples":[{"de":"Das ist nur eine vorläufige Lösung.","en":"This is only a temporary solution.","ru":"Это лишь временное решение.","vi":"Đây chỉ là giải pháp tạm thời.","fa":"این فقط یک راه حل موقت است."},{"de":"Vorläufig bleiben wir in dieser Wohnung.","en":"For now, we're staying in this apartment.","ru":"Пока что мы остаёмся в этой квартире.","vi":"Bây giờ chúng ta sẽ ở trong căn hộ này.","fa":"فعلاً در این آپارتمان خواهیم ماند."}]},{"word":"vorlesen","en":"to read aloud","ru":"читать вслух","vi":"đọc to","fa":"خواندن","examples":[{"de":"Die Mutter liest ihrem Kind jeden Abend eine Geschichte vor.","en":"The mother reads a story aloud to her child every evening.","ru":"Мать каждый вечер читает ребёнку сказку вслух.","vi":"Mẹ đọc truyện cho con nghe vào mỗi buổi tối.","fa":"مادر هر روز عصر برای فرزندش قصه می خواند."},{"de":"Kannst du mir bitte den Brief vorlesen?","en":"Can you please read the letter aloud to me?","ru":"Можешь прочитать мне это письмо вслух?","vi":"Bạn có thể vui lòng đọc thư cho tôi được không?","fa":"میشه لطفا نامه رو برای من بخونید؟"}]},{"word":"vorn","en":"in front, at the front","ru":"впереди","vi":"phía trước","fa":"جلو","examples":[{"de":"Setz dich vorn ins Auto.","en":"Sit in the front of the car.","ru":"Садись впереди в машине.","vi":"Ngồi ở phía trước xe.","fa":"جلوی ماشین بنشینید."},{"de":"In der Schlange stand er ganz vorn.","en":"He stood right at the front of the line.","ru":"В очереди он стоял совсем впереди.","vi":"Anh ấy đã ở phía trước của hàng đợi.","fa":"جلوی صف بود."}]},{"word":"der Vorort","en":"suburb","ru":"пригород","vi":"vùng ngoại ô","fa":"حومه شهر","examples":[{"de":"Wir wohnen in einem Vorort von München.","en":"We live in a suburb of Munich.","ru":"Мы живём в пригороде Мюнхена.","vi":"Chúng tôi sống ở ngoại ô Munich.","fa":"ما در حومه مونیخ زندگی می کنیم."},{"de":"In den Vororten sind die Mieten günstiger als in der Stadt.","en":"Rents are cheaper in the suburbs than in the city.","ru":"В пригородах аренда дешевле, чем в городе.","vi":"Giá thuê nhà ở ngoại ô rẻ hơn trong thành phố.","fa":"اجاره در حومه شهر ارزان تر از شهر است."}]},{"word":"der Vorrat","en":"supply","ru":"запас","vi":"cổ phiếu","fa":"سهام","examples":[{"de":"Wir haben einen großen Vorrat an Nudeln im Schrank.","en":"We have a large supply of pasta in the cupboard.","ru":"У нас в шкафу большой запас макарон.","vi":"Chúng tôi có một lượng lớn mì ống trong tủ.","fa":"ما مقدار زیادی پاستا در کمد داریم."},{"de":"Mein Vorrat an Kaffee geht langsam zur Neige.","en":"My supply of coffee is slowly running low.","ru":"Мой запас кофе медленно подходит к концу.","vi":"Nguồn cà phê của tôi đang dần cạn kiệt.","fa":"ذخایر قهوه ام کم کم تمام می شود."},{"de":"Im Winter legen viele Menschen einen Vorrat an.","en":"In winter many people build up a supply.","ru":"Зимой многие люди делают запасы.","vi":"Vào mùa đông, nhiều người dự trữ.","fa":"در زمستان، بسیاری از مردم انبار می کنند."}]},{"word":"der Vorschlag","en":"suggestion; proposal","ru":"предложение","vi":"lời đề nghị","fa":"پیشنهاد","examples":[{"de":"Ich möchte einen Vorschlag machen.","en":"I would like to make a suggestion.","ru":"Я хотел бы внести предложение.","vi":"Tôi muốn đưa ra một đề nghị.","fa":"من می خواهم یک پیشنهاد بدهم."},{"de":"Ihr Vorschlag wurde von allen sofort angenommen.","en":"Your proposal was immediately accepted by everyone.","ru":"Ваше предложение сразу приняли все.","vi":"Đề nghị của cô ngay lập tức được mọi người chấp nhận.","fa":"پیشنهاد او بلافاصله مورد قبول همه قرار گرفت."}]},{"word":"vorschlagen","en":"to suggest, to propose","ru":"предлагать","vi":"đề nghị","fa":"پیشنهاد می کند","examples":[{"de":"Ich schlage vor, dass wir uns morgen treffen.","en":"I suggest that we meet tomorrow.","ru":"Я предлагаю встретиться завтра.","vi":"Tôi đề nghị chúng ta gặp nhau vào ngày mai.","fa":"پیشنهاد میکنم فردا همدیگه رو ببینیم"},{"de":"Er hat einen guten Kompromiss vorgeschlagen.","en":"He proposed a good compromise.","ru":"Он предложил хороший компромисс.","vi":"Ông đề nghị một sự thỏa hiệp tốt.","fa":"او یک سازش خوب را پیشنهاد کرد."}]},{"word":"die Vorschrift","en":"regulation, rule","ru":"предписание, правило","vi":"quy định","fa":"مقررات","examples":[{"de":"Man muss sich an die Vorschriften halten.","en":"You have to follow the regulations.","ru":"Нужно соблюдать предписания.","vi":"Bạn phải tuân theo các quy tắc.","fa":"شما باید قوانین را رعایت کنید."},{"de":"Diese Vorschrift gilt für alle Mitarbeiter.","en":"This regulation applies to all employees.","ru":"Это правило действует для всех сотрудников.","vi":"Quy định này áp dụng cho tất cả nhân viên.","fa":"این آیین نامه برای همه کارکنان اعمال می شود."}]},{"word":"die Vorsicht","en":"caution, care","ru":"осторожность","vi":"sự thận trọng","fa":"احتیاط","examples":[{"de":"Vorsicht, die Straße ist glatt!","en":"Caution, the road is slippery!","ru":"Осторожно, дорога скользкая!","vi":"Hãy cẩn thận, đường trơn trượt!","fa":"مراقب باشید، جاده لغزنده است!"},{"de":"Mit Vorsicht sollte man solche Angebote betrachten.","en":"You should view such offers with caution.","ru":"К таким предложениям следует относиться с осторожностью.","vi":"Những đề nghị như vậy nên được xem xét một cách thận trọng.","fa":"چنین پیشنهادهایی را باید با احتیاط دید."}]},{"word":"die Vorspeise","en":"starter, appetiser","ru":"закуска (первое блюдо перед основным)","vi":"sự khởi đầu","fa":"استارتر","examples":[{"de":"Als Vorspeise nehme ich eine kleine Suppe.","en":"As a starter I will have a small soup.","ru":"На закуску я возьму небольшой суп.","vi":"Khi bắt đầu, tôi có một món súp nhỏ.","fa":"به عنوان پیش غذا یک سوپ کوچک دارم."},{"de":"Die Vorspeise war so groß, dass ich kaum noch Hunger hatte.","en":"The starter was so big that I was hardly hungry any more.","ru":"Закуска была такой большой, что я уже почти не был голоден.","vi":"Món khai vị quá lớn đến nỗi tôi hầu như không đói.","fa":"استارتر آنقدر بزرگ بود که به سختی گرسنه بودم."},{"de":"Im Menü ist eine Vorspeise inbegriffen.","en":"A starter is included in the set menu.","ru":"В меню закуска включена.","vi":"Thực đơn bao gồm một món khai vị.","fa":"منو شامل یک پیش غذا است."}]},{"word":"die Vorstellung","en":"idea; performance; introduction","ru":"представление; показ","vi":"ý tưởng","fa":"ایده","examples":[{"de":"Ich habe keine Vorstellung, wie teuer das ist.","en":"I have no idea how expensive that is.","ru":"Я понятия не имею, насколько это дорого.","vi":"Tôi không biết nó đắt thế nào.","fa":"من نمی دانم چقدر گران است."},{"de":"Die Vorstellung im Theater beginnt um acht.","en":"The performance at the theatre starts at eight.","ru":"Спектакль в театре начинается в восемь.","vi":"Buổi biểu diễn ở nhà hát bắt đầu lúc tám giờ.","fa":"اجرا در تئاتر از ساعت هشت شروع می شود."}]},{"word":"das Vorstellungsgespräch","en":"job interview","ru":"собеседование","vi":"cuộc phỏng vấn","fa":"مصاحبه","examples":[{"de":"Morgen habe ich ein Vorstellungsgespräch bei einer neuen Firma.","en":"Tomorrow I have a job interview at a new company.","ru":"Завтра у меня собеседование в новой компании.","vi":"Ngày mai tôi có cuộc phỏng vấn ở một công ty mới.","fa":"فردا در یک شرکت جدید مصاحبه دارم."},{"de":"Sie hat sich gut auf das Vorstellungsgespräch vorbereitet.","en":"She prepared well for the job interview.","ru":"Она хорошо подготовилась к собеседованию.","vi":"Cô ấy đã chuẩn bị tốt cho cuộc phỏng vấn.","fa":"او به خوبی برای مصاحبه آماده شد."}]},{"word":"das Vorstellungsgespräch führen","en":"to conduct a job interview","ru":"провести собеседование (о приёме на работу)","vi":"tiến hành cuộc phỏng vấn","fa":"مصاحبه را انجام دهید","examples":[{"de":"Morgen muss ich ein Vorstellungsgespräch führen.","en":"Tomorrow I have to attend a job interview.","ru":"Завтра мне нужно пройти собеседование.","vi":"Ngày mai tôi phải phỏng vấn.","fa":"فردا باید مصاحبه کنم"},{"de":"Die Chefin führte das Vorstellungsgespräch sehr freundlich.","en":"The boss conducted the interview very kindly.","ru":"Начальница провела собеседование очень дружелюбно.","vi":"Sếp đã thực hiện cuộc phỏng vấn một cách rất thân thiện.","fa":"رئیس مصاحبه را بسیار دوستانه انجام داد."},{"de":"Vor dem Vorstellungsgespräch war er sehr nervös.","en":"Before the interview he was very nervous.","ru":"Перед собеседованием он очень нервничал.","vi":"Anh ấy rất lo lắng trước cuộc phỏng vấn.","fa":"قبل از مصاحبه خیلی عصبی بود."}]},{"word":"der Vorteil","en":"advantage","ru":"преимущество","vi":"lợi thế","fa":"مزیت","examples":[{"de":"Ein großer Vorteil dieser Wohnung ist die zentrale Lage.","en":"A big advantage of this apartment is its central location.","ru":"Большое преимущество этой квартиры — центральное расположение.","vi":"Một lợi thế lớn của căn hộ này là vị trí trung tâm.","fa":"مزیت بزرگ این آپارتمان موقعیت مرکزی آن است."},{"de":"Welche Vorteile hat das neue System?","en":"What advantages does the new system have?","ru":"Какие преимущества у новой системы?","vi":"Ưu điểm của hệ thống mới là gì?","fa":"مزایای سیستم جدید چیست؟"}]},{"word":"der Vortrag","en":"lecture, presentation","ru":"доклад, лекция","vi":"bài giảng","fa":"سخنرانی","examples":[{"de":"Der Professor hielt einen interessanten Vortrag über Klimawandel.","en":"The professor gave an interesting lecture on climate change.","ru":"Профессор прочитал интересный доклад об изменении климата.","vi":"Giáo sư đã có một bài giảng thú vị về biến đổi khí hậu.","fa":"استاد سخنرانی جالبی در مورد تغییرات آب و هوا ارائه کرد."},{"de":"Ich muss morgen einen Vortrag vor der Klasse halten.","en":"I have to give a presentation in front of the class tomorrow.","ru":"Завтра мне нужно выступить с докладом перед классом.","vi":"Ngày mai tôi phải giảng bài cho lớp.","fa":"فردا باید سر کلاس سخنرانی کنم."}]},{"word":"das Vorurteil","en":"prejudice","ru":"предрассудок, предубеждение","vi":"định kiến","fa":"تعصب","examples":[{"de":"Viele Menschen haben Vorurteile gegen Fremde.","en":"Many people have prejudices against strangers.","ru":"У многих людей есть предрассудки в отношении чужаков.","vi":"Nhiều người có thành kiến với người lạ.","fa":"بسیاری از مردم نسبت به غریبه ها تعصب دارند."},{"de":"Bildung kann helfen, Vorurteile abzubauen.","en":"Education can help to break down prejudices.","ru":"Образование может помочь избавиться от предрассудков.","vi":"Giáo dục có thể giúp giảm bớt định kiến.","fa":"آموزش می تواند به کاهش تعصبات کمک کند."},{"de":"Ihr Vorurteil verschwand, als sie ihn kennenlernte.","en":"Her prejudice disappeared when she got to know him.","ru":"Её предубеждение исчезло, когда она с ним познакомилась.","vi":"Định kiến ​​của cô biến mất khi cô gặp anh.","fa":"تعصب او با ملاقات با او از بین رفت."}]},{"word":"das Vorurteil abbauen","en":"to break down prejudice","ru":"преодолевать предрассудки, изживать предубеждения","vi":"giảm bớt định kiến","fa":"تعصب را کاهش دهید","examples":[{"de":"Begegnungen helfen, Vorurteile abzubauen.","en":"Encounters help to break down prejudices.","ru":"Встречи помогают преодолевать предрассудки.","vi":"Những cuộc gặp gỡ giúp phá bỏ những định kiến.","fa":"برخوردها به از بین بردن تعصبات کمک می کند."},{"de":"Die Schule will Vorurteile zwischen den Gruppen abbauen.","en":"The school wants to break down prejudices between the groups.","ru":"Школа хочет преодолеть предрассудки между группами.","vi":"Nhà trường muốn giảm bớt định kiến ​​giữa các nhóm.","fa":"مدرسه می خواهد تعصبات بین گروه ها را کاهش دهد."},{"de":"Es braucht Zeit, alte Vorurteile abzubauen.","en":"It takes time to break down old prejudices.","ru":"Нужно время, чтобы изжить старые предрассудки.","vi":"Cần có thời gian để phá bỏ những định kiến ​​cũ.","fa":"شکستن تعصبات قدیمی زمان می برد."}]},{"word":"die Vorwahl","en":"area code, dial code","ru":"код города/страны (телефонный)","vi":"mã vùng","fa":"کد منطقه","examples":[{"de":"Wie lautet die Vorwahl von Berlin?","en":"What is the area code for Berlin?","ru":"Какой телефонный код у Берлина?","vi":"Mã vùng của Berlin là gì?","fa":"کد منطقه ای برلین چیست؟"},{"de":"Ohne die richtige Vorwahl kann ich dich nicht anrufen.","en":"Without the correct dial code, I can't call you.","ru":"Без правильного кода я не смогу тебе позвонить.","vi":"Tôi không thể gọi cho bạn nếu không có mã vùng chính xác.","fa":"من نمی توانم بدون کد منطقه صحیح با شما تماس بگیرم."}]},{"word":"vorwärts","en":"forward","ru":"вперёд","vi":"phía trước","fa":"به جلو","examples":[{"de":"Geh drei Schritte vorwärts.","en":"Take three steps forward.","ru":"Сделай три шага вперёд.","vi":"Tiến lên phía trước ba bước.","fa":"سه قدم به جلو بردارید."},{"de":"Das Projekt kommt langsam vorwärts.","en":"The project is slowly moving forward.","ru":"Проект медленно продвигается вперёд.","vi":"Dự án đang dần tiến triển.","fa":"این پروژه کم کم در حال پیشرفت است."}]},{"word":"der Vorwurf","en":"reproach, accusation","ru":"упрёк, обвинение","vi":"lời buộc tội","fa":"اتهام","examples":[{"de":"Sie machte ihm den Vorwurf, nie zuzuhören.","en":"She accused him of never listening.","ru":"Она упрекнула его в том, что он никогда не слушает.","vi":"Cô buộc tội anh không bao giờ lắng nghe.","fa":"او را متهم کرد که هرگز گوش نمی دهد."},{"de":"Ich mache dir keinen Vorwurf, es war nicht deine Schuld.","en":"I'm not blaming you, it wasn't your fault.","ru":"Я не упрекаю тебя, это была не твоя вина.","vi":"Tôi không trách bạn, đó không phải lỗi của bạn.","fa":"من تو را سرزنش نمی کنم، تقصیر تو نبود."}]},{"word":"waagerecht","en":"horizontal","ru":"горизонтальный","vi":"theo chiều ngang","fa":"به صورت افقی","examples":[{"de":"Bitte hängen Sie das Bild waagerecht auf.","en":"Please hang the picture horizontally.","ru":"Пожалуйста, повесьте картину горизонтально.","vi":"Hãy treo bức tranh theo chiều ngang.","fa":"لطفا تصویر را به صورت افقی آویزان کنید."},{"de":"Die Linie muss genau waagerecht verlaufen.","en":"The line must run exactly horizontally.","ru":"Линия должна идти строго горизонтально.","vi":"Đường này phải nằm ngang chính xác.","fa":"خط باید دقیقاً افقی باشد."}]},{"word":"waagrecht","en":"horizontal, level (variant of waagerecht)","ru":"горизонтальный (вариант написания waagerecht)","vi":"theo chiều ngang","fa":"به صورت افقی","examples":[{"de":"Die Wasseroberfläche ist immer waagrecht.","en":"The surface of water is always horizontal.","ru":"Поверхность воды всегда горизонтальна.","vi":"Mặt nước luôn nằm ngang.","fa":"سطح آب همیشه افقی است."},{"de":"Stell die Flasche nicht waagrecht hin, sonst läuft sie aus.","en":"Do not lay the bottle horizontally, or it will leak.","ru":"Не клади бутылку горизонтально, иначе она протечёт.","vi":"Không đặt chai theo chiều ngang nếu không nó sẽ bị rò rỉ.","fa":"بطری را به صورت افقی قرار ندهید وگرنه نشتی خواهد داشت."},{"de":"Im Kreuzworträtsel steht das Wort waagrecht.","en":"In the crossword the word goes across.","ru":"В кроссворде слово идёт по горизонтали.","vi":"Từ ngang có trong trò chơi ô chữ.","fa":"کلمه افقی در جدول کلمات متقاطع وجود دارد."}]},{"word":"wach","en":"awake","ru":"бодрствующий, не спящий","vi":"thức dậy","fa":"بیدار","examples":[{"de":"Um sechs Uhr war ich schon wach.","en":"I was already awake at six o'clock.","ru":"В шесть часов я уже не спал.","vi":"Tôi đã thức dậy lúc sáu giờ.","fa":"من قبلاً ساعت شش بیدار بودم."},{"de":"Der Kaffee hilft mir, wach zu bleiben.","en":"Coffee helps me stay awake.","ru":"Кофе помогает мне не засыпать.","vi":"Cà phê giúp tôi tỉnh táo.","fa":"قهوه به من کمک می کند بیدار بمانم."}]},{"word":"wachsen","en":"to grow","ru":"расти","vi":"phát triển","fa":"رشد کنند","examples":[{"de":"Die Pflanze wächst sehr schnell im Sommer.","en":"The plant grows very quickly in summer.","ru":"Растение очень быстро растёт летом.","vi":"Cây phát triển rất nhanh vào mùa hè.","fa":"این گیاه در تابستان خیلی سریع رشد می کند."},{"de":"Kinder wachsen in den ersten Jahren am schnellsten.","en":"Children grow the fastest in the first years.","ru":"Дети растут быстрее всего в первые годы.","vi":"Trẻ em phát triển nhanh nhất trong những năm đầu đời.","fa":"بچه ها در سال های اول زندگی سریع ترین رشد می کنند."}]},{"word":"der Wagen","en":"car; carriage","ru":"машина; вагон","vi":"chiếc xe","fa":"ماشین","examples":[{"de":"Er parkt seinen Wagen vor dem Haus.","en":"He parks his car in front of the house.","ru":"Он паркует свою машину перед домом.","vi":"Anh đậu xe trước nhà.","fa":"ماشینش را جلوی در خانه پارک می کند."},{"de":"Der Zug hat zehn Wagen.","en":"The train has ten carriages.","ru":"У поезда десять вагонов.","vi":"Đoàn tàu có mười toa.","fa":"قطار ده واگن دارد."}]},{"word":"die Wahl","en":"election; choice","ru":"выборы; выбор","vi":"sự lựa chọn","fa":"انتخاب","examples":[{"de":"Bei der Wahl haben viele Menschen abgestimmt.","en":"Many people voted in the election.","ru":"На выборах проголосовало много людей.","vi":"Nhiều người đã bỏ phiếu trong cuộc bầu cử.","fa":"افراد زیادی در انتخابات رای دادند."},{"de":"Du hast die Wahl zwischen Tee und Kaffee.","en":"You have the choice between tea and coffee.","ru":"У тебя есть выбор между чаем и кофе.","vi":"Bạn có sự lựa chọn giữa trà và cà phê.","fa":"شما بین چای و قهوه انتخاب دارید."}]},{"word":"wählen","en":"to choose; to vote","ru":"выбирать; голосовать","vi":"chọn","fa":"انتخاب کنید","examples":[{"de":"Ich muss zwischen zwei Angeboten wählen.","en":"I have to choose between two offers.","ru":"Мне нужно выбрать между двумя предложениями.","vi":"Tôi phải lựa chọn giữa hai lời đề nghị.","fa":"من باید بین دو پیشنهاد یکی را انتخاب کنم."},{"de":"Am Sonntag wählen die Bürger einen neuen Bürgermeister.","en":"On Sunday the citizens vote for a new mayor.","ru":"В воскресенье граждане выбирают нового мэра.","vi":"Vào Chủ nhật, người dân sẽ bầu một thị trưởng mới.","fa":"روز یکشنبه شهروندان شهردار جدید را انتخاب خواهند کرد."}]},{"word":"wahnsinnig","en":"crazy; incredibly (intensifier)","ru":"сумасшедший; ужасно, очень","vi":"mất trí","fa":"مجنون","examples":[{"de":"Das Konzert war wahnsinnig laut.","en":"The concert was incredibly loud.","ru":"Концерт был ужасно громким.","vi":"Buổi hòa nhạc cực kỳ ồn ào.","fa":"کنسرت فوق العاده بلند بود."},{"de":"Er wurde wahnsinnig vor Wut.","en":"He went crazy with rage.","ru":"Он сошёл с ума от ярости.","vi":"Anh ta nổi điên lên vì giận dữ.","fa":"از عصبانیت دیوانه شد."}]},{"word":"wahr","en":"true","ru":"истинный, правдивый","vi":"đúng","fa":"درست است","examples":[{"de":"Ist es wahr, dass du umziehst?","en":"Is it true that you're moving?","ru":"Правда ли, что ты переезжаешь?","vi":"Có đúng là bạn đang di chuyển?","fa":"آیا این درست است که شما در حال حرکت هستید؟"},{"de":"Seine Geschichte war leider nicht wahr.","en":"Unfortunately, his story wasn't true.","ru":"К сожалению, его история была неправдой.","vi":"Thật không may, câu chuyện của anh ấy không có thật.","fa":"متاسفانه داستان او درست نبود."}]},{"word":"während","en":"during; while","ru":"во время; пока","vi":"trong khi","fa":"در حالی که","examples":[{"de":"Während des Urlaubs habe ich viel gelesen.","en":"During the vacation I read a lot.","ru":"Во время отпуска я много читал.","vi":"Tôi đọc rất nhiều trong kỳ nghỉ.","fa":"در تعطیلات زیاد مطالعه می کنم."},{"de":"Während sie kochte, deckte er den Tisch.","en":"While she was cooking, he set the table.","ru":"Пока она готовила, он накрывал на стол.","vi":"Trong khi cô nấu ăn, anh dọn bàn ăn.","fa":"در حالی که او آشپزی می کرد، سفره را چید."}]},{"word":"die Wahrheit","en":"truth","ru":"правда, истина","vi":"sự thật","fa":"حقیقت","examples":[{"de":"Bitte sag mir endlich die Wahrheit.","en":"Please tell me the truth at last.","ru":"Скажи мне наконец правду.","vi":"Cuối cùng hãy nói cho tôi biết sự thật.","fa":"لطفا در نهایت حقیقت را به من بگویید."},{"de":"Die Wahrheit kommt früher oder später ans Licht.","en":"The truth comes to light sooner or later.","ru":"Правда рано или поздно выходит наружу.","vi":"Sự thật sớm hay muộn sẽ lộ ra.","fa":"حقیقت دیر یا زود آشکار خواهد شد."},{"de":"In Wahrheit hatte er gar keine Zeit.","en":"In truth he had no time at all.","ru":"На самом деле у него совсем не было времени.","vi":"Thực sự thì anh không có chút thời gian nào cả.","fa":"راستش اصلا وقت نداشت."}]},{"word":"wahrnehmen","en":"to perceive; to notice; to take up","ru":"воспринимать; замечать","vi":"nhận thức","fa":"درک کنند","examples":[{"de":"Aus der Ferne konnte er nur Umrisse wahrnehmen.","en":"From a distance he could only make out outlines.","ru":"Издалека он мог различить лишь очертания.","vi":"Từ xa anh chỉ có thể nhìn thấy những đường nét.","fa":"از دور فقط می توانست خطوط کلی را ببیند."},{"de":"Sie hat den Termin leider nicht wahrgenommen.","en":"Unfortunately she didn't keep the appointment.","ru":"К сожалению, она не явилась на назначенную встречу.","vi":"Thật không may là cô ấy đã không giữ lời hẹn.","fa":"متأسفانه او قرار ملاقات را رعایت نکرد."}]},{"word":"wahrscheinlich","en":"probably","ru":"вероятно","vi":"có lẽ","fa":"احتمالا","examples":[{"de":"Es wird wahrscheinlich morgen regnen.","en":"It will probably rain tomorrow.","ru":"Завтра, вероятно, пойдёт дождь.","vi":"Có lẽ ngày mai trời sẽ mưa.","fa":"احتمالا فردا باران خواهد بارید."},{"de":"Er kommt wahrscheinlich zu spät.","en":"He'll probably be late.","ru":"Он, вероятно, опоздает.","vi":"Có lẽ anh ấy đến muộn.","fa":"احتمالا دیر کرده"}]},{"word":"die Währung","en":"currency","ru":"валюта","vi":"tiền tệ","fa":"the currency","examples":[{"de":"Der Euro ist die Währung vieler europäischer Länder.","en":"The euro is the currency of many European countries.","ru":"Евро — валюта многих европейских стран.","vi":"Đồng euro là tiền tệ của nhiều nước châu Âu.","fa":"یورو واحد پول بسیاری از کشورهای اروپایی است."},{"de":"Vor der Reise tausche ich die Währung um.","en":"Before the trip I exchange the currency.","ru":"Перед поездкой я обмениваю валюту.","vi":"Trước chuyến đi tôi đổi tiền.","fa":"قبل از سفر ارز را عوض می کنم."},{"de":"Die Währung des Landes hat stark an Wert verloren.","en":"The country's currency has lost a lot of value.","ru":"Валюта страны сильно потеряла в стоимости.","vi":"Đồng tiền của đất nước đã mất rất nhiều giá trị.","fa":"پول این کشور ارزش زیادی از دست داده است."}]},{"word":"der Wald","en":"forest","ru":"лес","vi":"rừng","fa":"جنگل","examples":[{"de":"Wir machen einen Spaziergang im Wald.","en":"We're going for a walk in the forest.","ru":"Мы гуляем в лесу.","vi":"Chúng tôi đi dạo trong rừng.","fa":"در جنگل قدم می زنیم."},{"de":"Im Wald leben viele Tiere.","en":"Many animals live in the forest.","ru":"В лесу живёт много животных.","vi":"Nhiều loài động vật sống trong rừng.","fa":"حیوانات زیادی در جنگل زندگی می کنند."}]},{"word":"der Waldbrand","en":"forest fire, wildfire","ru":"лесной пожар","vi":"cháy rừng","fa":"آتش سوزی جنگل","examples":[{"de":"Wegen der langen Trockenheit gab es in diesem Sommer viele Waldbrände.","en":"Because of the long drought there were many forest fires this summer.","ru":"Из-за долгой засухи этим летом было много лесных пожаров.","vi":"Vì hạn hán kéo dài nên mùa hè năm nay xảy ra nhiều vụ cháy rừng.","fa":"به دلیل خشکسالی طولانی، در تابستان امسال آتش سوزی های بسیاری رخ داد."},{"de":"Ein einziger Funke kann einen großen Waldbrand auslösen.","en":"A single spark can trigger a large forest fire.","ru":"Одна-единственная искра может вызвать большой лесной пожар.","vi":"Một tia lửa duy nhất có thể gây ra một đám cháy rừng lớn.","fa":"یک جرقه می تواند آتش سوزی بزرگی در جنگل ایجاد کند."},{"de":"Die Feuerwehr kämpfte tagelang gegen den Waldbrand.","en":"The fire brigade fought the wildfire for days.","ru":"Пожарные несколько дней боролись с лесным пожаром.","vi":"Lực lượng chức năng chữa cháy rừng nhiều ngày.","fa":"آتش نشانی روزها با آتش سوزی جنگل مبارزه کرد."}]},{"word":"die Wand","en":"wall","ru":"стена","vi":"bức tường","fa":"دیوار","examples":[{"de":"An der Wand hängt ein Bild.","en":"A picture hangs on the wall.","ru":"На стене висит картина.","vi":"Có một bức tranh treo trên tường.","fa":"یک عکس روی دیوار آویزان است."},{"de":"Wir streichen die Wände neu.","en":"We're repainting the walls.","ru":"Мы заново красим стены.","vi":"Chúng tôi đang sơn lại các bức tường.","fa":"ما دیوارها را دوباره رنگ می کنیم."}]},{"word":"der Wandel","en":"change, transformation (social)","ru":"изменение, перемены (в обществе)","vi":"sự thay đổi","fa":"تغییر","examples":[{"de":"Die Gesellschaft befindet sich in einem ständigen Wandel.","en":"Society is in a state of constant change.","ru":"Общество находится в постоянном изменении.","vi":"Xã hội luôn thay đổi.","fa":"جامعه در حال تغییر دائمی است."},{"de":"Der soziale Wandel betrifft alle Generationen.","en":"Social change affects all generations.","ru":"Социальные перемены затрагивают все поколения.","vi":"Sự thay đổi xã hội ảnh hưởng đến tất cả các thế hệ.","fa":"تغییرات اجتماعی بر همه نسل ها تأثیر می گذارد."},{"de":"Ein schneller Wandel kann auch Ängste auslösen.","en":"Rapid change can also trigger fears.","ru":"Быстрые перемены могут вызывать и страхи.","vi":"Sự thay đổi nhanh chóng cũng có thể gây ra nỗi sợ hãi.","fa":"تغییر سریع همچنین می تواند باعث ایجاد ترس شود."}]},{"word":"wandern","en":"to hike","ru":"путешествовать пешком, ходить в поход","vi":"đi lang thang","fa":"پیاده روی","examples":[{"de":"Am Wochenende wandern wir in den Bergen.","en":"On the weekend we hike in the mountains.","ru":"На выходных мы ходим в поход в горы.","vi":"Vào cuối tuần chúng tôi đi leo núi.","fa":"آخر هفته در کوه پیاده روی می کنیم."},{"de":"Sie wandert gern durch den Wald.","en":"She likes hiking through the forest.","ru":"Она любит гулять по лесу.","vi":"Cô ấy thích đi bộ xuyên rừng.","fa":"او پیاده روی در جنگل را دوست دارد."}]},{"word":"die Wandertour","en":"hiking tour","ru":"пеший поход, поход","vi":"chuyến đi bộ đường dài","fa":"تور پیاده روی","examples":[{"de":"Am Wochenende machen wir eine Wandertour in den Bergen.","en":"At the weekend we're going on a hiking tour in the mountains.","ru":"На выходных мы идём в поход в горы.","vi":"Vào cuối tuần, chúng tôi đi du lịch leo núi.","fa":"در آخر هفته به یک تور پیاده روی در کوه می رویم."},{"de":"Die Wandertour führte uns durch dichte Wälder.","en":"The hiking tour led us through dense forests.","ru":"Поход провёл нас через густые леса.","vi":"Chuyến đi bộ đường dài đưa chúng tôi băng qua những khu rừng rậm rạp.","fa":"تور پیاده روی ما را از میان جنگل های انبوه برد."},{"de":"Für die Wandertour brauchst du feste Schuhe.","en":"For the hiking tour you need sturdy shoes.","ru":"Для похода нужна прочная обувь.","vi":"Bạn cần một đôi giày chắc chắn cho chuyến đi bộ đường dài.","fa":"برای تور پیاده روی به کفش های محکم نیاز دارید."}]},{"word":"die Wanderung","en":"hike, walk","ru":"поход, прогулка","vi":"chuyến đi bộ đường dài","fa":"پیاده روی","examples":[{"de":"Die Wanderung zum Gipfel war anstrengend, aber schön.","en":"The hike to the summit was exhausting but beautiful.","ru":"Поход к вершине был утомительным, но красивым.","vi":"Đường lên đỉnh núi vất vả nhưng đẹp đẽ.","fa":"مسیر صعود به قله سخت اما زیبا بود."},{"de":"Wir planen eine Wanderung entlang des Flusses.","en":"We're planning a hike along the river.","ru":"Мы планируем поход вдоль реки.","vi":"Chúng tôi đang lên kế hoạch đi bộ dọc bờ sông.","fa":"در حال برنامه ریزی برای پیاده روی در کنار رودخانه هستیم."},{"de":"Nach der Wanderung waren wir alle sehr müde.","en":"After the hike we were all very tired.","ru":"После похода мы все очень устали.","vi":"Sau chuyến đi bộ tất cả chúng tôi đều rất mệt mỏi.","fa":"بعد از پیاده روی همه ما خیلی خسته بودیم."}]},{"word":"die Wandrung","en":"hike, walk (contracted form of Wanderung)","ru":"поход, прогулка (стяжённая форма слова Wanderung)","vi":"chuyến đi bộ đường dài","fa":"پیاده روی","examples":[{"de":"Im Dialekt sagt man manchmal „Wandrung“ statt Wanderung.","en":"In dialect people sometimes say 'Wandrung' instead of Wanderung.","ru":"В диалекте иногда говорят «Wandrung» вместо «Wanderung».","vi":"Trong phương ngữ đôi khi bạn nói “hike” thay vì Hike.","fa":"در گویش شما گاهی به جای پیاده روی می گویید «هیک»."},{"de":"Die Wandrung durch das Tal war wunderschön.","en":"The hike through the valley was beautiful.","ru":"Поход по долине был прекрасным.","vi":"Việc đi bộ qua thung lũng thật đẹp.","fa":"پیاده روی در دره زیبا بود."},{"de":"Nach der langen Wandrung gönnten wir uns eine Pause.","en":"After the long hike we treated ourselves to a break.","ru":"После долгого похода мы позволили себе передышку.","vi":"Sau chuyến đi bộ dài, chúng tôi tự thưởng cho mình một khoảng thời gian nghỉ ngơi.","fa":"پس از پیاده‌روی طولانی مدت استراحت کردیم."}]},{"word":"wann","en":"when","ru":"когда","vi":"khi nào","fa":"چه زمانی","examples":[{"de":"Wann beginnt der Film?","en":"When does the movie start?","ru":"Когда начинается фильм?","vi":"Khi nào bộ phim bắt đầu?","fa":"فیلم کی شروع میشه؟"},{"de":"Ich weiß nicht, wann er ankommt.","en":"I don't know when he'll arrive.","ru":"Я не знаю, когда он приедет.","vi":"Tôi không biết khi nào anh ấy sẽ đến.","fa":"نمی دانم کی می آید."}]},{"word":"die Ware","en":"goods; merchandise","ru":"товар","vi":"hàng hóa","fa":"کالاها","examples":[{"de":"Die Ware wird morgen geliefert.","en":"The goods will be delivered tomorrow.","ru":"Товар доставят завтра.","vi":"Hàng hóa sẽ được giao vào ngày mai.","fa":"کالا فردا تحویل داده می شود."},{"de":"Im Laden gibt es viele verschiedene Waren.","en":"The shop has many different goods.","ru":"В магазине много разных товаров.","vi":"Có rất nhiều hàng hóa khác nhau trong cửa hàng.","fa":"اجناس مختلف زیادی در فروشگاه وجود دارد."}]},{"word":"der Warenkorb","en":"shopping basket (also online)","ru":"корзина покупок (в т. ч. онлайн)","vi":"giỏ hàng","fa":"سبد خرید","examples":[{"de":"Ich habe drei Bücher in den Warenkorb gelegt.","en":"I put three books in the shopping basket.","ru":"Я положил три книги в корзину.","vi":"Tôi bỏ ba cuốn sách vào giỏ hàng.","fa":"سه کتاب را در سبد خرید گذاشتم."},{"de":"Klicken Sie auf den Warenkorb, um Ihre Bestellung abzuschließen.","en":"Click on the shopping basket to complete your order.","ru":"Нажми на корзину, чтобы оформить заказ.","vi":"Bấm vào giỏ hàng để hoàn tất đơn hàng.","fa":"برای تکمیل سفارش خود روی سبد خرید کلیک کنید."},{"de":"Mein Warenkorb war voller als geplant.","en":"My shopping basket was fuller than planned.","ru":"Моя корзина оказалась полнее, чем планировалось.","vi":"Giỏ hàng của tôi đã đầy hơn dự kiến.","fa":"سبد خرید من پر از برنامه بود."}]},{"word":"warm","en":"warm","ru":"тёплый","vi":"ấm áp","fa":"گرم","examples":[{"de":"Heute ist es sehr warm draußen.","en":"It's very warm outside today.","ru":"Сегодня на улице очень тепло.","vi":"Hôm nay ngoài trời rất ấm áp.","fa":"امروز بیرون خیلی گرمه"},{"de":"Ich trinke gern warmen Tee.","en":"I like drinking warm tea.","ru":"Я люблю пить тёплый чай.","vi":"Tôi thích uống trà ấm.","fa":"من دوست دارم چای گرم بنوشم."}]},{"word":"die Wärmedämmung","en":"thermal insulation","ru":"теплоизоляция","vi":"cách nhiệt","fa":"عایق حرارتی","examples":[{"de":"Eine gute Wärmedämmung spart viel Heizenergie.","en":"Good thermal insulation saves a lot of heating energy.","ru":"Хорошая теплоизоляция экономит много энергии на отопление.","vi":"Cách nhiệt tốt giúp tiết kiệm rất nhiều năng lượng sưởi ấm.","fa":"عایق حرارتی خوب باعث صرفه جویی زیادی در انرژی گرمایشی می شود."},{"de":"Das alte Haus hat fast keine Wärmedämmung.","en":"The old house has almost no thermal insulation.","ru":"У старого дома почти нет теплоизоляции.","vi":"Ngôi nhà cũ gần như không có khả năng cách nhiệt.","fa":"خانه قدیمی تقریبا هیچ عایق حرارتی ندارد."},{"de":"Mit einer neuen Wärmedämmung wird es im Winter wärmer.","en":"With new thermal insulation it gets warmer in winter.","ru":"С новой теплоизоляцией зимой становится теплее.","vi":"Với vật liệu cách nhiệt mới, nó sẽ ấm hơn vào mùa đông.","fa":"با عایق حرارتی جدید در زمستان گرمتر خواهد بود."}]},{"word":"die Wärmepumpe","en":"heat pump","ru":"тепловой насос","vi":"máy bơm nhiệt","fa":"پمپ حرارتی","examples":[{"de":"Eine Wärmepumpe heizt das Haus klimafreundlich.","en":"A heat pump heats the house in a climate-friendly way.","ru":"Тепловой насос отапливает дом щадяще для климата.","vi":"Máy bơm nhiệt làm nóng ngôi nhà theo cách thân thiện với khí hậu.","fa":"یک پمپ حرارتی خانه را به روشی سازگار با آب و هوا گرم می کند."},{"de":"Immer mehr Familien lassen eine Wärmepumpe einbauen.","en":"More and more families are having a heat pump installed.","ru":"Всё больше семей устанавливают тепловой насос.","vi":"Ngày càng có nhiều gia đình lắp đặt máy bơm nhiệt.","fa":"خانواده های بیشتری در حال نصب پمپ حرارتی هستند."},{"de":"Die Wärmepumpe nutzt die Wärme aus der Erde.","en":"The heat pump uses the warmth from the ground.","ru":"Тепловой насос использует тепло из земли.","vi":"Máy bơm nhiệt sử dụng nhiệt từ trái đất.","fa":"پمپ حرارتی از گرمای زمین استفاده می کند."}]},{"word":"warnen","en":"to warn","ru":"предупреждать","vi":"cảnh báo","fa":"هشدار دهد","examples":[{"de":"Der Arzt warnt vor zu viel Zucker.","en":"The doctor warns against too much sugar.","ru":"Врач предупреждает об избытке сахара.","vi":"Bác sĩ cảnh báo không nên ăn quá nhiều đường.","fa":"پزشک نسبت به مصرف بیش از حد قند هشدار می دهد."},{"de":"Sie warnte mich vor der Gefahr.","en":"She warned me about the danger.","ru":"Она предупредила меня об опасности.","vi":"Cô ấy đã cảnh báo tôi về sự nguy hiểm.","fa":"او به من در مورد خطر هشدار داد."}]},{"word":"warten","en":"to wait","ru":"ждать","vi":"chờ đã","fa":"صبر کن","examples":[{"de":"Ich warte seit einer Stunde auf den Bus.","en":"I've been waiting for the bus for an hour.","ru":"Я жду автобус уже час.","vi":"Tôi đã đợi xe buýt được một giờ rồi.","fa":"یک ساعتی است که منتظر اتوبوس هستم."},{"de":"Bitte warten Sie einen Moment.","en":"Please wait a moment.","ru":"Пожалуйста, подождите минутку.","vi":"Xin vui lòng chờ một lát.","fa":"لطفا یک لحظه صبر کنید."}]},{"word":"die Wartung","en":"maintenance","ru":"техническое обслуживание, обслуживание","vi":"việc bảo trì","fa":"تعمیر و نگهداری","examples":[{"de":"Wegen einer Wartung ist die Webseite heute nicht erreichbar.","en":"Because of maintenance the website is unavailable today.","ru":"Из-за технического обслуживания сайт сегодня недоступен.","vi":"Trang web không hoạt động ngày hôm nay do bảo trì.","fa":"وب سایت امروز به دلیل تعمیر در دسترس نیست."},{"de":"Die Wartung des Servers findet meistens nachts statt.","en":"The maintenance of the server usually takes place at night.","ru":"Обслуживание сервера обычно проходит ночью.","vi":"Việc bảo trì máy chủ thường diễn ra vào ban đêm.","fa":"تعمیر و نگهداری سرور معمولا در شب انجام می شود."},{"de":"Während der Wartung kannst du dich nicht anmelden.","en":"During the maintenance you can't log in.","ru":"Во время обслуживания ты не можешь войти в систему.","vi":"Bạn không thể đăng nhập trong thời gian bảo trì.","fa":"در طول تعمیر و نگهداری نمی توانید وارد شوید."}]},{"word":"warum","en":"why","ru":"почему","vi":"tại sao","fa":"چرا","examples":[{"de":"Warum bist du so traurig?","en":"Why are you so sad?","ru":"Почему ты такой грустный?","vi":"Tại sao bạn lại buồn thế?","fa":"چرا اینقدر غمگینی؟"},{"de":"Ich verstehe nicht, warum er nicht anruft.","en":"I don't understand why he doesn't call.","ru":"Я не понимаю, почему он не звонит.","vi":"Tôi không hiểu tại sao anh ấy không gọi.","fa":"نمیفهمم چرا زنگ نمیزنه"}]},{"word":"was","en":"what","ru":"что","vi":"cái gì","fa":"چی","examples":[{"de":"Was machst du heute Abend?","en":"What are you doing tonight?","ru":"Что ты делаешь сегодня вечером?","vi":"Tối nay bạn đang làm gì?","fa":"امشب چیکار میکنی؟"},{"de":"Was hast du gesagt?","en":"What did you say?","ru":"Что ты сказал?","vi":"Bạn đã nói gì?","fa":"چی گفتی؟"}]},{"word":"Was bedeutet …?","en":"What does … mean? (asking meaning)","ru":"Что значит …? (вопрос о значении)","vi":"có nghĩa là gì?","fa":"... یعنی چی؟","examples":[{"de":"Was bedeutet dieses Wort?","en":"What does this word mean?","ru":"Что значит это слово?","vi":"Từ này có nghĩa là gì?","fa":"این کلمه به چه معناست؟"}]},{"word":"was für ein-","en":"what kind of","ru":"какой, что за","vi":"cái gì-","fa":"چی الف-","examples":[{"de":"Was für ein Auto hast du?","en":"What kind of car do you have?","ru":"Какая у тебя машина?","vi":"Bạn có loại xe nào?","fa":"چه نوع ماشینی دارید؟"},{"de":"Was für eine gute Idee!","en":"What a good idea!","ru":"Какая хорошая идея!","vi":"Thật là một ý tưởng hay!","fa":"چه ایده خوبی!"}]},{"word":"Was hältst du von …?","en":"What do you think of …? (asking opinion)","ru":"Что ты думаешь о …? (запрос мнения)","vi":"Bạn nghĩ gì về…?","fa":"نظر شما در مورد…؟","examples":[{"de":"Was hältst du von diesem Vorschlag?","en":"What do you think of this suggestion?","ru":"Что ты думаешь об этом предложении?","vi":"Bạn nghĩ gì về đề xuất này?","fa":"نظر شما در مورد این پیشنهاد چیست؟"}]},{"word":"die Waschmaschine","en":"washing machine","ru":"стиральная машина","vi":"máy giặt","fa":"ماشین لباسشویی","examples":[{"de":"Die Waschmaschine läuft gerade, deshalb ist es so laut.","en":"The washing machine is running, that's why it's so loud.","ru":"Стиральная машина сейчас работает, поэтому так шумно.","vi":"Máy giặt hiện đang chạy nên kêu to như vậy.","fa":"ماشین لباسشویی در حال حاضر کار می کند، به همین دلیل صدای آن بسیار زیاد است."},{"de":"Ich räume die Waschmaschine aus und hänge die Wäsche auf.","en":"I empty the washing machine and hang up the laundry.","ru":"Я разгружаю стиральную машину и развешиваю бельё.","vi":"Tôi đổ hết đồ trong máy giặt và treo đồ giặt.","fa":"ماشین لباسشویی را خالی می کنم و لباس های شسته شده را آویزان می کنم."},{"de":"Unsere alte Waschmaschine ist leider kaputtgegangen.","en":"Unfortunately our old washing machine broke down.","ru":"Наша старая стиральная машина, к сожалению, сломалась.","vi":"Thật không may, chiếc máy giặt cũ của chúng tôi bị hỏng.","fa":"متاسفانه ماشین لباسشویی قدیمی ما خراب شد."}]},{"word":"das Waschmittel","en":"detergent, washing powder","ru":"стиральный порошок, моющее средство для стирки","vi":"chất tẩy rửa","fa":"مواد شوینده","examples":[{"de":"Das Waschmittel ist alle, ich muss neues kaufen.","en":"The detergent has run out, I need to buy new.","ru":"Стиральный порошок закончился, нужно купить новый.","vi":"Tôi đã hết bột giặt và phải mua cái mới.","fa":"مواد شوینده من تمام شده و باید مواد شوینده جدید بخرم."},{"de":"Verwende nicht zu viel Waschmittel für eine Ladung.","en":"Don't use too much detergent for one load.","ru":"Не используй слишком много порошка на одну загрузку.","vi":"Không sử dụng quá nhiều bột giặt trong một lần giặt.","fa":"از مواد شوینده زیاد در یک بار استفاده نکنید."},{"de":"Dieses Waschmittel ist besonders gut für empfindliche Haut.","en":"This detergent is especially good for sensitive skin.","ru":"Этот порошок особенно хорош для чувствительной кожи.","vi":"Chất tẩy rửa này đặc biệt tốt cho làn da nhạy cảm.","fa":"این شوینده به ویژه برای پوست های حساس مفید است."}]},{"word":"das Wasser","en":"water","ru":"вода","vi":"nước","fa":"آب","examples":[{"de":"Ich trinke jeden Tag viel Wasser.","en":"I drink a lot of water every day.","ru":"Я пью много воды каждый день.","vi":"Tôi uống rất nhiều nước mỗi ngày.","fa":"من هر روز مقدار زیادی آب می نوشم."},{"de":"Das Wasser im See ist sehr kalt.","en":"The water in the lake is very cold.","ru":"Вода в озере очень холодная.","vi":"Nước trong hồ rất lạnh.","fa":"آب دریاچه بسیار سرد است."}]},{"word":"die Wasserkraft","en":"hydropower, water power","ru":"гидроэнергия, энергия воды","vi":"thủy điện","fa":"برق آبی","examples":[{"de":"In den Bergen wird viel Strom aus Wasserkraft erzeugt.","en":"In the mountains a lot of electricity is generated from hydropower.","ru":"В горах много электричества вырабатывают из гидроэнергии.","vi":"Rất nhiều điện được tạo ra từ thủy điện trên núi.","fa":"مقدار زیادی برق از نیروگاه های آبی در کوه ها تولید می شود."},{"de":"Wasserkraft gehört zu den erneuerbaren Energien.","en":"Hydropower is one of the renewable energies.","ru":"Гидроэнергия относится к возобновляемым видам энергии.","vi":"Thủy điện là một trong những nguồn năng lượng tái tạo.","fa":"برق آبی یکی از انرژی های تجدیدپذیر است."},{"de":"Das Kraftwerk nutzt die Wasserkraft eines großen Flusses.","en":"The power station uses the water power of a large river.","ru":"Электростанция использует энергию воды большой реки.","vi":"Nhà máy điện sử dụng năng lượng thủy điện của một con sông lớn.","fa":"این نیروگاه از نیروی برق آبی یک رودخانه بزرگ استفاده می کند."}]},{"word":"der Wasserstoff","en":"hydrogen","ru":"водород","vi":"hydro","fa":"هیدروژن","examples":[{"de":"Wasserstoff gilt als Energie der Zukunft.","en":"Hydrogen is seen as the energy of the future.","ru":"Водород считают энергией будущего.","vi":"Hydro được coi là năng lượng của tương lai.","fa":"هیدروژن انرژی آینده در نظر گرفته می شود."},{"de":"Manche Autos fahren bereits mit Wasserstoff.","en":"Some cars already run on hydrogen.","ru":"Некоторые машины уже ездят на водороде.","vi":"Một số ô tô đã chạy bằng hydro.","fa":"برخی از خودروها در حال حاضر با هیدروژن کار می کنند."},{"de":"Grüner Wasserstoff wird aus Ökostrom hergestellt.","en":"Green hydrogen is produced from renewable electricity.","ru":"Зелёный водород производят из возобновляемого электричества.","vi":"Hydro xanh được sản xuất từ ​​điện xanh.","fa":"هیدروژن سبز از برق سبز تولید می شود."}]},{"word":"das Wasserwerk","en":"waterworks","ru":"водопроводная станция, водоканал","vi":"nhà máy nước","fa":"آبرسانی","examples":[{"de":"Das Wasserwerk versorgt die ganze Stadt mit Trinkwasser.","en":"The waterworks supplies the whole city with drinking water.","ru":"Водоканал снабжает весь город питьевой водой.","vi":"Các nhà máy nước cung cấp nước uống cho toàn bộ thành phố.","fa":"آب شرب کل شهر را تامین می کند."},{"de":"Im Wasserwerk wird das Wasser gereinigt und kontrolliert.","en":"In the waterworks the water is cleaned and monitored.","ru":"На водопроводной станции воду очищают и контролируют.","vi":"Nước được làm sạch và kiểm soát trong các nhà máy nước.","fa":"آب در شبکه آب تمیز و کنترل می شود."},{"de":"Das alte Wasserwerk wurde zu einem Museum umgebaut.","en":"The old waterworks was converted into a museum.","ru":"Старую водопроводную станцию превратили в музей.","vi":"Các nhà máy nước cũ đã được chuyển đổi thành bảo tàng.","fa":"آبرسانی قدیمی به موزه تبدیل شد."}]},{"word":"das Webinar","en":"webinar","ru":"вебинар","vi":"hội thảo trực tuyến","fa":"وبینار","examples":[{"de":"Nächste Woche nehme ich an einem Webinar über Marketing teil.","en":"Next week I'm taking part in a webinar on marketing.","ru":"На следующей неделе я участвую в вебинаре по маркетингу.","vi":"Tuần tới tôi sẽ tham gia một hội thảo trực tuyến về tiếp thị.","fa":"هفته آینده در یک وبینار درباره بازاریابی شرکت خواهم کرد."},{"de":"Das Webinar findet online statt und ist kostenlos.","en":"The webinar takes place online and is free.","ru":"Вебинар проходит онлайн и бесплатно.","vi":"Hội thảo trực tuyến diễn ra trực tuyến và miễn phí.","fa":"وبینار به صورت آنلاین برگزار می شود و رایگان است."},{"de":"Während des Webinars konnte man Fragen im Chat stellen.","en":"During the webinar you could ask questions in the chat.","ru":"Во время вебинара можно было задавать вопросы в чате.","vi":"Trong hội thảo trên web, bạn có thể đặt câu hỏi trong cuộc trò chuyện.","fa":"در طول وبینار می توانید سوالات خود را در چت بپرسید."}]},{"word":"der Wechselkurs","en":"exchange rate","ru":"обменный курс","vi":"tỷ giá hối đoái","fa":"the exchange rate","examples":[{"de":"Der Wechselkurs für den Dollar ist heute günstig.","en":"The exchange rate for the dollar is favourable today.","ru":"Обменный курс доллара сегодня выгодный.","vi":"Tỷ giá hối đoái của đồng đô la ngày nay thuận lợi.","fa":"نرخ دلار امروز مطلوب است."},{"de":"Wegen des schlechten Wechselkurses warte ich noch.","en":"Because of the poor exchange rate, I'm still waiting.","ru":"Из-за плохого обменного курса я ещё жду.","vi":"Tôi vẫn đang chờ đợi vì tỷ giá hối đoái xấu.","fa":"به خاطر نرخ بد ارز همچنان منتظرم."},{"de":"Der Wechselkurs ändert sich jeden Tag.","en":"The exchange rate changes every day.","ru":"Обменный курс меняется каждый день.","vi":"Tỷ giá hối đoái thay đổi mỗi ngày.","fa":"نرخ ارز هر روز تغییر می کند."}]},{"word":"wechseln","en":"to change; to exchange","ru":"менять; обменивать","vi":"chuyển đổi","fa":"سوئیچ","examples":[{"de":"Ich muss den Reifen wechseln.","en":"I have to change the tire.","ru":"Мне нужно поменять шину.","vi":"Tôi phải thay lốp.","fa":"باید لاستیک رو عوض کنم"},{"de":"Wo kann ich Geld wechseln?","en":"Where can I exchange money?","ru":"Где я могу обменять деньги?","vi":"Tôi có thể đổi tiền ở đâu?","fa":"کجا پول عوض کنم؟"}]},{"word":"wecken","en":"to wake (someone) up","ru":"будить","vi":"thức dậy","fa":"بیدار شو","examples":[{"de":"Der Wecker weckt mich um sechs Uhr.","en":"The alarm clock wakes me up at six.","ru":"Будильник будит меня в шесть.","vi":"Đồng hồ báo thức đánh thức tôi dậy lúc sáu giờ.","fa":"ساعت زنگ دار من را ساعت شش بیدار می کند."},{"de":"Bitte weck mich nicht so früh.","en":"Please don't wake me up so early.","ru":"Пожалуйста, не буди меня так рано.","vi":"Làm ơn đừng đánh thức tôi dậy sớm thế.","fa":"لطفا اینقدر زود بیدارم نکن"}]},{"word":"der Wecker","en":"alarm clock","ru":"будильник","vi":"đồng hồ báo thức","fa":"ساعت زنگ دار","examples":[{"de":"Mein Wecker klingelt jeden Morgen um halb sieben.","en":"My alarm clock rings every morning at half past six.","ru":"Мой будильник звонит каждое утро в половине седьмого.","vi":"Chuông báo thức của tôi reo vào mỗi buổi sáng lúc bảy giờ rưỡi.","fa":"زنگ ساعت من هر روز صبح ساعت هفت و نیم به صدا در می آید."},{"de":"Gestern habe ich den Wecker einfach überhört.","en":"Yesterday I simply slept through the alarm clock.","ru":"Вчера я просто не услышал будильник.","vi":"Hôm qua tôi chỉ đơn giản là phớt lờ đồng hồ báo thức.","fa":"دیروز به سادگی زنگ ساعت را نادیده گرفتم."},{"de":"Stell den Wecker bitte eine Stunde früher.","en":"Please set the alarm clock an hour earlier.","ru":"Поставь, пожалуйста, будильник на час раньше.","vi":"Vui lòng đặt báo thức sớm hơn một giờ.","fa":"لطفا زنگ ساعت خود را یک ساعت زودتر تنظیم کنید."}]},{"word":"weder","en":"neither (weder ... noch = neither ... nor)","ru":"ни (weder ... noch = ни ... ни)","vi":"cũng không","fa":"نه","examples":[{"de":"Ich habe weder Zeit noch Lust dazu.","en":"I have neither the time nor the desire for it.","ru":"У меня нет на это ни времени, ни желания.","vi":"Tôi không có thời gian hay mong muốn cho nó.","fa":"من زمان و تمایلی برای آن ندارم."},{"de":"Er spricht weder Englisch noch Französisch.","en":"He speaks neither English nor French.","ru":"Он не говорит ни по-английски, ни по-французски.","vi":"Anh ấy không nói được tiếng Anh hay tiếng Pháp.","fa":"او انگلیسی یا فرانسوی صحبت نمی کند."},{"de":"Weder sie noch ihr Bruder waren zu Hause.","en":"Neither she nor her brother were at home.","ru":"Ни она, ни её брат не были дома.","vi":"Cả cô và anh trai cô đều không có nhà.","fa":"نه او و نه برادرش خانه نبودند."}]},{"word":"weder … noch","en":"neither ... nor","ru":"ни ... ни","vi":"không…cũng không","fa":"نه… نه","examples":[{"de":"Ich mag weder Kaffee noch Tee.","en":"I like neither coffee nor tea.","ru":"Я не люблю ни кофе, ни чай.","vi":"Tôi không thích cà phê hay trà.","fa":"من قهوه یا چای دوست ندارم."},{"de":"Er hat weder angerufen noch geschrieben.","en":"He neither called nor wrote.","ru":"Он ни позвонил, ни написал.","vi":"Anh ấy không gọi điện hay viết thư.","fa":"نه زنگ زد و نه نوشت."}]},{"word":"der Weg","en":"way; path","ru":"путь, дорога","vi":"con đường","fa":"راه","examples":[{"de":"Können Sie mir den Weg zum Bahnhof zeigen?","en":"Can you show me the way to the station?","ru":"Вы можете показать мне дорогу к вокзалу?","vi":"Bạn có thể chỉ cho tôi đường đến ga xe lửa được không?","fa":"می توانید راه ایستگاه قطار را به من نشان دهید؟"},{"de":"Der Weg durch den Wald ist sehr schön.","en":"The path through the forest is very beautiful.","ru":"Тропа через лес очень красивая.","vi":"Con đường xuyên rừng rất đẹp.","fa":"مسیر میان جنگل بسیار زیباست."}]},{"word":"weg-","en":"away (separable prefix: weggehen, wegfahren, wegnehmen)","ru":"прочь (отделяемая приставка: weggehen — уходить, wegwerfen — выбрасывать)","vi":"đi xa-","fa":"دور-","examples":[{"de":"Geh bitte nicht weg, ich bin gleich zurück.","en":"Please do not go away, I will be right back.","ru":"Пожалуйста, не уходи, я сейчас вернусь.","vi":"Làm ơn đừng đi xa, tôi sẽ quay lại ngay.","fa":"لطفا نرو، من بلافاصله برمی گردم."},{"de":"Er hat seine alten Schuhe weggeworfen.","en":"He threw his old shoes away.","ru":"Он выбросил свою старую обувь.","vi":"Anh ấy đã vứt đôi giày cũ của mình đi.","fa":"کفش های کهنه اش را دور انداخت."},{"de":"Nimm dem Kind das Messer weg!","en":"Take the knife away from the child!","ru":"Забери у ребёнка нож!","vi":"Hãy lấy con dao ra khỏi đứa trẻ!","fa":"چاقو را از دست کودک بردارید!"}]},{"word":"wegen","en":"because of","ru":"из-за","vi":"bởi vì","fa":"به دلیل","examples":[{"de":"Wegen des Regens bleiben wir zu Hause.","en":"Because of the rain we're staying home.","ru":"Из-за дождя мы остаёмся дома.","vi":"Vì trời mưa nên chúng tôi ở nhà.","fa":"به خاطر باران در خانه می مانیم."},{"de":"Sie ist wegen der Prüfung sehr nervös.","en":"She's very nervous because of the exam.","ru":"Она очень нервничает из-за экзамена.","vi":"Cô ấy rất lo lắng về kỳ thi.","fa":"او در مورد امتحان بسیار عصبی است."}]},{"word":"weg/weg-","en":"away, gone","ru":"прочь, отсутствующий","vi":"đi/đi xa-","fa":"دور / دور -","examples":[{"de":"Meine Tasche ist plötzlich weg.","en":"My bag is suddenly gone.","ru":"Моя сумка вдруг пропала.","vi":"Túi của tôi đột nhiên biến mất.","fa":"کیف من ناگهان از بین رفت."},{"de":"Geh weg von der Straße!","en":"Get away from the street!","ru":"Отойди от дороги!","vi":"Hãy ra khỏi đường phố!","fa":"از خیابان برو!"}]},{"word":"wegwerfen","en":"to throw away, to discard","ru":"выбрасывать","vi":"vứt đi","fa":"دور انداختن","examples":[{"de":"Wirf das alte Brot bitte nicht weg.","en":"Please do not throw the old bread away.","ru":"Пожалуйста, не выбрасывай старый хлеб.","vi":"Xin đừng vứt bánh mì cũ đi.","fa":"لطفا نان کهنه را دور نریزید."},{"de":"Wir werfen viel zu viele Lebensmittel weg.","en":"We throw away far too much food.","ru":"Мы выбрасываем слишком много еды.","vi":"Chúng ta vứt bỏ quá nhiều thức ăn","fa":"ما غذای زیادی را دور می اندازیم."},{"de":"Sie hat die kaputte Tasse weggeworfen.","en":"She threw away the broken cup.","ru":"Она выбросила разбитую чашку.","vi":"Cô ném chiếc cốc vỡ đi.","fa":"لیوان شکسته را دور انداخت."}]},{"word":"wehtun","en":"to hurt","ru":"болеть, причинять боль","vi":"đau","fa":"صدمه دیده","examples":[{"de":"Mein Kopf tut weh.","en":"My head hurts.","ru":"У меня болит голова.","vi":"Đầu tôi đau quá.","fa":"سرم درد میکنه"},{"de":"Seine Worte haben mir sehr wehgetan.","en":"His words hurt me a lot.","ru":"Его слова очень меня задели.","vi":"Lời nói của anh làm tôi tổn thương rất nhiều.","fa":"حرف هایش مرا خیلی آزار داد."}]},{"word":"weiblich","en":"female; feminine","ru":"женский","vi":"nữ","fa":"زن","examples":[{"de":"Das weibliche Geschlecht ist hier in der Mehrheit.","en":"The female sex is in the majority here.","ru":"Женский пол здесь в большинстве.","vi":"Ở đây giới tính nữ chiếm đa số.","fa":"جنس زن در اینجا اکثریت است."},{"de":"„die“ ist ein weiblicher Artikel.","en":"'die' is a feminine article.","ru":"«die» — женский артикль.","vi":"“die” là một mạo từ nữ tính.","fa":"«بمیر» یک مقاله زنانه است."}]},{"word":"weich","en":"soft","ru":"мягкий","vi":"mềm mại","fa":"نرم","examples":[{"de":"Das Kissen ist sehr weich.","en":"The pillow is very soft.","ru":"Подушка очень мягкая.","vi":"Gối rất mềm.","fa":"بالش بسیار نرم است."},{"de":"Ich mag weiches Brot lieber als hartes.","en":"I prefer soft bread to hard bread.","ru":"Я предпочитаю мягкий хлеб твёрдому.","vi":"Tôi thích bánh mì mềm hơn bánh mì cứng.","fa":"من نان نرم را بهتر از نان سفت دوست دارم."}]},{"word":"weigern","en":"to refuse (sich weigern = to refuse to do something)","ru":"отказываться (sich weigern — отказываться что-либо делать)","vi":"từ chối","fa":"رد کردن","examples":[{"de":"Er weigert sich, die Wahrheit zu sagen.","en":"He refuses to tell the truth.","ru":"Он отказывается говорить правду.","vi":"Anh ta từ chối nói sự thật.","fa":"او حاضر به گفتن حقیقت نیست."},{"de":"Das Kind weigerte sich, ins Bett zu gehen.","en":"The child refused to go to bed.","ru":"Ребёнок отказался идти спать.","vi":"Đứa trẻ không chịu đi ngủ.","fa":"کودک از رفتن به رختخواب خودداری کرد."},{"de":"Die Arbeiter weigern sich, ohne Bezahlung weiterzumachen.","en":"The workers refuse to carry on without pay.","ru":"Рабочие отказываются продолжать без оплаты.","vi":"Các công nhân từ chối tiếp tục làm việc mà không được trả lương.","fa":"کارگران از ادامه کار بدون دستمزد خودداری می کنند."}]},{"word":"weil","en":"because","ru":"потому что","vi":"bởi vì","fa":"چون","examples":[{"de":"Ich bleibe zu Hause, weil ich krank bin.","en":"I'm staying home because I'm sick.","ru":"Я остаюсь дома, потому что я болен.","vi":"Tôi đang ở nhà vì tôi bị ốm.","fa":"من در خانه می مانم چون مریض هستم."},{"de":"Wir gehen früh, weil der Zug bald fährt.","en":"We're leaving early because the train departs soon.","ru":"Мы уходим рано, потому что поезд скоро отправляется.","vi":"Chúng tôi khởi hành sớm vì tàu sắp khởi hành.","fa":"ما زود حرکت می کنیم زیرا قطار به زودی حرکت می کند."}]},{"word":"der Wein","en":"wine","ru":"вино","vi":"rượu vang","fa":"شراب","examples":[{"de":"Zum Essen trinken wir ein Glas Wein.","en":"We drink a glass of wine with the meal.","ru":"За едой мы пьём бокал вина.","vi":"Chúng tôi uống một ly rượu trong bữa ăn.","fa":"با غذا یک لیوان شراب می نوشیم."},{"de":"Dieser Wein kommt aus Italien.","en":"This wine is from Italy.","ru":"Это вино из Италии.","vi":"Loại rượu này đến từ Ý.","fa":"این شراب از ایتالیا می آید."}]},{"word":"weinen","en":"to cry","ru":"плакать","vi":"khóc","fa":"گریه کن","examples":[{"de":"Das Baby weint, weil es Hunger hat.","en":"The baby is crying because it's hungry.","ru":"Малыш плачет, потому что голоден.","vi":"Bé khóc vì đói.","fa":"نوزاد به دلیل گرسنگی گریه می کند."},{"de":"Sie musste vor Freude weinen.","en":"She had to cry with joy.","ru":"Она заплакала от радости.","vi":"Cô đã phải khóc vì sung sướng.","fa":"مجبور شد از خوشحالی گریه کند."}]},{"word":"weit","en":"far; wide","ru":"далёкий, широкий","vi":"xa","fa":"دور","examples":[{"de":"Die Schule ist nicht weit von hier.","en":"The school is not far from here.","ru":"Школа недалеко отсюда.","vi":"Trường học cách đây không xa.","fa":"مدرسه از اینجا دور نیست."},{"de":"Er trägt gern weite Hosen.","en":"He likes wearing wide, loose pants.","ru":"Он любит носить широкие брюки.","vi":"Anh ấy thích mặc quần rộng.","fa":"او دوست دارد شلوار گشاد بپوشد."}]},{"word":"weiter","en":"further; on, continuing","ru":"дальше, далее","vi":"hơn nữa","fa":"بیشتر","examples":[{"de":"Bitte lesen Sie weiter.","en":"Please continue reading.","ru":"Пожалуйста, читайте дальше.","vi":"Xin vui lòng đọc tiếp.","fa":"لطفا به ادامه مطلب بروید"},{"de":"Der nächste Ort liegt zehn Kilometer weiter.","en":"The next town is ten kilometers further.","ru":"Следующий населённый пункт находится на десять километров дальше.","vi":"Thị trấn tiếp theo cách xa hơn mười km.","fa":"شهر بعدی ده کیلومتر جلوتر است."}]},{"word":"die Weiterbildung","en":"further education, training","ru":"повышение квалификации","vi":"đào tạo thêm","fa":"آموزش بیشتر","examples":[{"de":"Meine Firma bietet Kurse zur Weiterbildung an.","en":"My company offers courses for further training.","ru":"Моя фирма предлагает курсы повышения квалификации.","vi":"Công ty của tôi cung cấp các khóa học giáo dục thường xuyên.","fa":"شرکت من دوره های آموزش مداوم را ارائه می دهد."},{"de":"Sie macht eine Weiterbildung im Bereich Informatik.","en":"She's doing further training in IT.","ru":"Она проходит повышение квалификации в сфере информатики.","vi":"Cô đang được đào tạo thêm trong lĩnh vực khoa học máy tính.","fa":"او در حال گذراندن دوره های آموزشی بیشتر در زمینه علوم کامپیوتر است."}]},{"word":"welcher","en":"which","ru":"который, какой","vi":"cái nào","fa":"کدام یک","examples":[{"de":"Welcher Bus fährt zum Zentrum?","en":"Which bus goes to the center?","ru":"Какой автобус едет в центр?","vi":"Xe buýt nào đi vào trung tâm?","fa":"کدام اتوبوس به مرکز می رود؟"},{"de":"Welche Farbe gefällt dir am besten?","en":"Which color do you like best?","ru":"Какой цвет тебе нравится больше всего?","vi":"Bạn thích màu nào nhất?","fa":"کدام رنگ را بیشتر دوست دارید؟"}]},{"word":"die Wellenlänge","en":"wavelength","ru":"длина волны","vi":"bước sóng","fa":"طول موج","examples":[{"de":"Rotes Licht hat eine längere Wellenlänge als blaues.","en":"Red light has a longer wavelength than blue.","ru":"У красного света длина волны больше, чем у синего.","vi":"Ánh sáng đỏ có bước sóng dài hơn ánh sáng xanh.","fa":"نور قرمز طول موج بیشتری نسبت به آبی دارد."},{"de":"Die Wellenlänge ist der Abstand zwischen zwei Wellenbergen.","en":"The wavelength is the distance between two wave crests.","ru":"Длина волны — это расстояние между двумя гребнями волны.","vi":"Bước sóng là khoảng cách giữa hai đỉnh sóng.","fa":"طول موج فاصله بین دو تاج موج است."},{"de":"Jede Farbe entspricht einer bestimmten Wellenlänge.","en":"Each colour corresponds to a particular wavelength.","ru":"Каждому цвету соответствует определённая длина волны.","vi":"Mỗi màu tương ứng với một bước sóng cụ thể.","fa":"هر رنگ مربوط به یک طول موج خاص است."}]},{"word":"der Wellnessurlaub","en":"spa/wellness holiday","ru":"оздоровительный (велнес-) отпуск","vi":"kỳ nghỉ chăm sóc sức khỏe","fa":"تعطیلات سلامتی","examples":[{"de":"Nach dem stressigen Jahr buchten wir einen Wellnessurlaub.","en":"After the stressful year we booked a wellness holiday.","ru":"После напряжённого года мы забронировали оздоровительный отпуск.","vi":"Sau một năm căng thẳng, chúng tôi đăng ký một kỳ nghỉ dưỡng sức khỏe.","fa":"بعد از سال پر استرس، یک تعطیلات سلامتی رزرو کردیم."},{"de":"Im Wellnessurlaub gibt es Massagen und eine Sauna.","en":"On the wellness holiday there are massages and a sauna.","ru":"В велнес-отпуске есть массаж и сауна.","vi":"Kỳ nghỉ chăm sóc sức khỏe bao gồm dịch vụ mát-xa và phòng xông hơi khô.","fa":"تعطیلات سلامتی شامل ماساژ و سونا است."},{"de":"Ein Wellnessurlaub in den Bergen klingt herrlich.","en":"A spa holiday in the mountains sounds wonderful.","ru":"Оздоровительный отпуск в горах звучит чудесно.","vi":"Một kỳ nghỉ dưỡng sức ở vùng núi nghe thật tuyệt vời.","fa":"تعطیلات سلامتی در کوهستان فوق العاده به نظر می رسد."}]},{"word":"die Welt","en":"world","ru":"мир","vi":"thế giới","fa":"جهان","examples":[{"de":"Er möchte die ganze Welt bereisen.","en":"He wants to travel the whole world.","ru":"Он хочет объездить весь мир.","vi":"Anh ấy muốn đi du lịch khắp thế giới.","fa":"او می خواهد تمام دنیا را سفر کند."},{"de":"Das Internet hat die Welt verändert.","en":"The internet has changed the world.","ru":"Интернет изменил мир.","vi":"Internet đã thay đổi thế giới.","fa":"اینترنت دنیا را تغییر داده است."}]},{"word":"das Weltall","en":"outer space, the universe","ru":"космос, Вселенная","vi":"vũ trụ","fa":"کیهان","examples":[{"de":"Das Weltall ist unvorstellbar groß und größtenteils leer.","en":"Outer space is unimaginably vast and largely empty.","ru":"Космос невообразимо огромен и по большей части пуст.","vi":"Vũ trụ rộng lớn không thể tưởng tượng được và hầu hết đều trống rỗng.","fa":"جهان به طور غیرقابل تصوری بزرگ و عمدتاً خالی است."},{"de":"Schon als Kind träumte sie davon, ins Weltall zu fliegen.","en":"Even as a child she dreamed of flying into space.","ru":"Ещё ребёнком она мечтала полететь в космос.","vi":"Ngay từ khi còn nhỏ, cô đã mơ ước được bay vào vũ trụ.","fa":"او حتی در کودکی آرزوی پرواز به فضا را داشت."},{"de":"Im Weltall gibt es weder oben noch unten.","en":"In outer space there is neither up nor down.","ru":"В космосе нет ни верха, ни низа.","vi":"Trong không gian không có lên cũng không có xuống.","fa":"در فضا نه بالا و نه پایین وجود دارد."}]},{"word":"weltenweit","en":"world-wide, across all the worlds","ru":"по всему свету, через все миры (устар./редкое)","vi":"trên toàn thế giới","fa":"در سراسر جهان","examples":[{"de":"Die Idee verbreitete sich weltenweit.","en":"The idea spread across the whole world.","ru":"Идея распространилась по всему свету.","vi":"Ý tưởng này lan rộng khắp thế giới.","fa":"این ایده در سراسر جهان گسترش یافت."},{"de":"Seine Träume reichten weltenweit.","en":"His dreams reached all across the world.","ru":"Его мечты простирались через все миры.","vi":"Ước mơ của anh đã vươn tới toàn thế giới.","fa":"رویاهای او به سراسر جهان رسید."},{"de":"Die Geschichte ist weltenweit bekannt.","en":"The story is known the world over.","ru":"История известна по всему свету.","vi":"Câu chuyện được biết đến trên toàn thế giới.","fa":"این داستان در سراسر جهان شناخته شده است."}]},{"word":"der Weltmeister","en":"world champion","ru":"чемпион мира","vi":"nhà vô địch thế giới","fa":"قهرمان جهان","examples":[{"de":"Die deutsche Mannschaft wurde 2014 Weltmeister.","en":"The German team became world champions in 2014.","ru":"В 2014 году сборная Германии стала чемпионом мира.","vi":"Đội tuyển Đức đã trở thành nhà vô địch thế giới vào năm 2014.","fa":"تیم آلمان در سال 2014 قهرمان جهان شد."},{"de":"Er träumt davon, eines Tages Weltmeister zu werden.","en":"He dreams of becoming world champion one day.","ru":"Он мечтает когда-нибудь стать чемпионом мира.","vi":"Anh mơ ước một ngày nào đó sẽ trở thành nhà vô địch thế giới.","fa":"او آرزو دارد روزی قهرمان جهان شود."},{"de":"Der Weltmeister verteidigte erfolgreich seinen Titel.","en":"The world champion successfully defended his title.","ru":"Чемпион мира успешно защитил свой титул.","vi":"Nhà vô địch thế giới đã bảo vệ thành công danh hiệu của mình.","fa":"قهرمان جهان با موفقیت از عنوان خود دفاع کرد."}]},{"word":"der Weltraum","en":"outer space","ru":"космос, космическое пространство","vi":"không gian","fa":"فضا","examples":[{"de":"Im Weltraum gibt es weder Luft noch Geräusche.","en":"In outer space there is neither air nor sound.","ru":"В космосе нет ни воздуха, ни звуков.","vi":"Không có không khí hay âm thanh trong không gian.","fa":"در فضا نه هوا وجود دارد و نه صدا."},{"de":"Viele Länder erforschen heute den Weltraum.","en":"Many countries explore outer space today.","ru":"Сегодня многие страны исследуют космос.","vi":"Nhiều quốc gia đang khám phá không gian ngày nay.","fa":"امروزه بسیاری از کشورها در حال کاوش در فضا هستند."},{"de":"Der Weltraum beginnt etwa hundert Kilometer über der Erde.","en":"Outer space begins about a hundred kilometres above the Earth.","ru":"Космос начинается примерно в ста километрах над Землёй.","vi":"Không gian bắt đầu cách Trái đất khoảng một trăm km.","fa":"فضا حدود صد کیلومتر بالاتر از زمین شروع می شود."}]},{"word":"weltweit","en":"worldwide, global","ru":"всемирный, глобальный","vi":"trên toàn thế giới","fa":"در سراسر جهان","examples":[{"de":"Die Firma ist weltweit tätig.","en":"The company operates worldwide.","ru":"Фирма работает по всему миру.","vi":"Công ty hoạt động trên toàn thế giới.","fa":"این شرکت در سراسر جهان فعالیت می کند."},{"de":"Weltweit leiden viele Menschen unter Armut.","en":"Worldwide, many people suffer from poverty.","ru":"По всему миру многие люди страдают от бедности.","vi":"Nhiều người trên khắp thế giới phải chịu cảnh nghèo đói.","fa":"بسیاری از مردم در سراسر جهان از فقر رنج می برند."},{"de":"Das Produkt wird weltweit verkauft.","en":"The product is sold worldwide.","ru":"Продукт продаётся по всему миру.","vi":"Sản phẩm được bán trên toàn thế giới.","fa":"این محصول در سراسر جهان به فروش می رسد."}]},{"word":"die Wende","en":"turnaround, turning point","ru":"поворот, перелом (кардинальная смена курса)","vi":"bước ngoặt","fa":"نقطه عطف","examples":[{"de":"Beim Klimaschutz brauchen wir endlich eine echte Wende.","en":"In climate protection we finally need a real turnaround.","ru":"В защите климата нам наконец нужен настоящий поворот.","vi":"Khi nói đến bảo vệ khí hậu, cuối cùng chúng ta cần một sự thay đổi thực sự.","fa":"وقتی صحبت از حفاظت از آب و هوا می شود، در نهایت به یک تغییر واقعی نیاز داریم."},{"de":"Die Wende hin zu sauberer Energie hat begonnen.","en":"The turn towards clean energy has begun.","ru":"Поворот к чистой энергии начался.","vi":"Quá trình chuyển đổi sang năng lượng sạch đã bắt đầu.","fa":"انتقال به سمت انرژی پاک آغاز شده است."},{"de":"Ohne eine Wende im Verkehr sinken die Emissionen nicht.","en":"Without a turnaround in transport, emissions will not fall.","ru":"Без поворота в транспорте выбросы не снизятся.","vi":"Nếu không có sự thay đổi trong vận tải, lượng khí thải sẽ không giảm.","fa":"بدون تغییر در حمل و نقل، انتشار گازهای گلخانه ای کاهش نخواهد یافت."}]},{"word":"wenden","en":"to turn","ru":"поворачивать, разворачивать","vi":"rẽ","fa":"چرخش","examples":[{"de":"Er musste auf der schmalen Straße wenden.","en":"He had to turn around on the narrow street.","ru":"Ему пришлось развернуться на узкой улице.","vi":"Anh phải quay đầu lại trên con đường hẹp.","fa":"مجبور شد در جاده باریک بپیچد."},{"de":"Bitte wenden Sie sich an die Rezeption.","en":"Please turn to the reception desk.","ru":"Пожалуйста, обратитесь на ресепшн.","vi":"Vui lòng liên hệ lễ tân.","fa":"لطفا با پذیرش تماس بگیرید"}]},{"word":"wenigstens","en":"at least","ru":"по крайней мере","vi":"ít nhất","fa":"حداقل","examples":[{"de":"Ruf mich wenigstens kurz an.","en":"At least give me a quick call.","ru":"Позвони мне хотя бы ненадолго.","vi":"Ít nhất hãy gọi cho tôi nhanh nhé.","fa":"حداقل یه زنگ سریع بزن"},{"de":"Wenigstens hat es nicht geregnet.","en":"At least it didn't rain.","ru":"По крайней мере, дождя не было.","vi":"Ít nhất thì trời không mưa.","fa":"حداقل باران نبارید."}]},{"word":"wenig/wenige","en":"little; few","ru":"мало, немного","vi":"ít/ít","fa":"کم/کم","examples":[{"de":"Ich habe heute wenig Zeit.","en":"I have little time today.","ru":"У меня сегодня мало времени.","vi":"Hôm nay tôi có ít thời gian.","fa":"امروز وقت کمی دارم"},{"de":"Nur wenige Leute kamen zur Party.","en":"Only a few people came to the party.","ru":"На вечеринку пришло лишь немного людей.","vi":"Chỉ có một vài người đến dự bữa tiệc.","fa":"فقط چند نفر به مهمانی آمدند."}]},{"word":"wenn","en":"if; when","ru":"если; когда","vi":"nếu","fa":"اگر","examples":[{"de":"Wenn es regnet, bleiben wir zu Hause.","en":"If it rains, we'll stay home.","ru":"Если пойдёт дождь, мы останемся дома.","vi":"Nếu trời mưa thì chúng ta ở nhà.","fa":"اگر باران ببارد، ما در خانه می مانیم."},{"de":"Wenn ich Zeit habe, rufe ich dich an.","en":"When I have time, I'll call you.","ru":"Когда у меня будет время, я тебе позвоню.","vi":"Khi nào có thời gian tôi sẽ gọi cho bạn.","fa":"وقتی وقت کنم بهت زنگ میزنم"}]},{"word":"wer","en":"who","ru":"кто","vi":"ai","fa":"چه کسی","examples":[{"de":"Wer ist diese Frau?","en":"Who is this woman?","ru":"Кто эта женщина?","vi":"Người phụ nữ này là ai?","fa":"این زن کیست؟"},{"de":"Ich weiß nicht, wer angerufen hat.","en":"I don't know who called.","ru":"Я не знаю, кто звонил.","vi":"Tôi không biết ai đã gọi.","fa":"نمیدونم کی زنگ زد"}]},{"word":"die Werbung","en":"advertising","ru":"реклама","vi":"quảng cáo","fa":"تبلیغات","examples":[{"de":"Im Fernsehen läuft viel Werbung.","en":"There's a lot of advertising on TV.","ru":"По телевизору много рекламы.","vi":"Có rất nhiều quảng cáo trên truyền hình.","fa":"تبلیغات زیادی در تلویزیون پخش می شود."},{"de":"Die Firma macht Werbung für ihr neues Produkt.","en":"The company is advertising its new product.","ru":"Компания рекламирует свой новый продукт.","vi":"Công ty đang quảng cáo sản phẩm mới của mình.","fa":"این شرکت در حال تبلیغ محصول جدید خود است."}]},{"word":"werden","en":"to become","ru":"становиться","vi":"trở thành","fa":"تبدیل شود","examples":[{"de":"Sie will Ärztin werden.","en":"She wants to become a doctor.","ru":"Она хочет стать врачом.","vi":"Cô ấy muốn trở thành một bác sĩ.","fa":"او می خواهد دکتر شود."},{"de":"Es wird langsam dunkel.","en":"It's slowly becoming dark.","ru":"Постепенно темнеет.","vi":"Trời đang dần tối.","fa":"کم کم داره تاریک میشه"}]},{"word":"werfen","en":"to throw","ru":"бросать","vi":"ném","fa":"پرتاب","examples":[{"de":"Er wirft den Ball zu seinem Freund.","en":"He throws the ball to his friend.","ru":"Он бросает мяч своему другу.","vi":"Anh ấy ném quả bóng cho bạn mình.","fa":"او توپ را به طرف دوستش پرتاب می کند."},{"de":"Wirf das Papier nicht auf den Boden!","en":"Don't throw the paper on the floor!","ru":"Не бросай бумагу на пол!","vi":"Đừng ném tờ giấy xuống sàn nhà!","fa":"کاغذ را روی زمین نریزید!"}]},{"word":"das Werk","en":"work, piece of work; factory, plant","ru":"произведение; завод","vi":"công việc","fa":"کار","examples":[{"de":"Dieses Gemälde ist ein bekanntes Werk des Künstlers.","en":"This painting is a well-known work of the artist.","ru":"Эта картина — известное произведение художника.","vi":"Bức tranh này là một tác phẩm nổi tiếng của họa sĩ.","fa":"این نقاشی از آثار شناخته شده این هنرمند است."},{"de":"Mein Vater arbeitet im Werk am Stadtrand.","en":"My father works at the plant on the edge of town.","ru":"Мой отец работает на заводе на окраине города.","vi":"Bố tôi làm việc tại nhà máy ở ngoại ô thị trấn.","fa":"پدرم در کارخانه ای در حومه شهر کار می کند."}]},{"word":"der Werktag","en":"working day; weekday","ru":"рабочий день, будний день","vi":"ngày làm việc","fa":"روز کاری","examples":[{"de":"An einem Werktag stehe ich um sechs Uhr auf.","en":"On a working day I get up at six o'clock.","ru":"В будний день я встаю в шесть часов.","vi":"Vào một ngày trong tuần, tôi thức dậy lúc sáu giờ.","fa":"در یک روز هفته من ساعت شش بیدار می شوم."},{"de":"Das Geschäft ist nur an Werktagen geöffnet.","en":"The shop is only open on working days.","ru":"Магазин открыт только по будним дням.","vi":"Cửa hàng chỉ mở cửa vào các ngày trong tuần.","fa":"فروشگاه فقط در روزهای هفته باز است."},{"de":"Die Lieferung kommt innerhalb von drei Werktagen.","en":"The delivery arrives within three working days.","ru":"Доставка придёт в течение трёх рабочих дней.","vi":"Giao hàng đến trong vòng ba ngày làm việc.","fa":"تحویل ظرف سه روز کاری انجام می شود."}]},{"word":"das Werkzeug","en":"tool; tools","ru":"инструмент","vi":"công cụ","fa":"ابزار","examples":[{"de":"Für die Reparatur brauche ich das richtige Werkzeug.","en":"I need the right tool for the repair.","ru":"Для ремонта мне нужен подходящий инструмент.","vi":"Tôi cần những công cụ phù hợp để sửa chữa.","fa":"برای تعمیر به ابزار مناسب نیاز دارم."},{"de":"Im Keller liegt das ganze Werkzeug in einer Kiste.","en":"All the tools are in a box in the cellar.","ru":"В подвале весь инструмент лежит в ящике.","vi":"Tất cả các dụng cụ đều được đựng trong một chiếc hộp ở tầng hầm.","fa":"همه ابزارها در یک جعبه در زیرزمین قرار دارند."},{"de":"Kannst du mir dein Werkzeug leihen?","en":"Can you lend me your tools?","ru":"Ты можешь одолжить мне свой инструмент?","vi":"Bạn có thể cho tôi mượn công cụ của bạn được không?","fa":"آیا می توانید ابزار خود را به من قرض دهید؟"}]},{"word":"wert","en":"worth","ru":"стоящий, ценный","vi":"giá trị","fa":"ارزش","examples":[{"de":"Der alte Ring ist viel Geld wert.","en":"The old ring is worth a lot of money.","ru":"Старое кольцо стоит много денег.","vi":"Chiếc nhẫn cũ có giá trị rất nhiều tiền.","fa":"انگشتر قدیمی ارزش پول زیادی دارد."},{"de":"Der Film ist es wert, gesehen zu werden.","en":"The movie is worth watching.","ru":"Фильм стоит того, чтобы его посмотреть.","vi":"Bộ phim rất đáng xem.","fa":"فیلم ارزش دیدن را دارد."}]},{"word":"der Wert","en":"value","ru":"ценность, значение","vi":"giá trị","fa":"ارزش","examples":[{"de":"Der Wert des Hauses ist gestiegen.","en":"The value of the house has increased.","ru":"Стоимость дома выросла.","vi":"Giá trị của ngôi nhà đã tăng lên.","fa":"ارزش خانه افزایش یافته است."},{"de":"Sie legt großen Wert auf Pünktlichkeit.","en":"She places great value on punctuality.","ru":"Она придаёт большое значение пунктуальности.","vi":"Cô ấy rất coi trọng việc đúng giờ.","fa":"او به وقت شناسی اهمیت زیادی می دهد."}]},{"word":"wertlos","en":"worthless, valueless","ru":"ничего не стоящий, бесполезный","vi":"vô giá trị","fa":"بی ارزش","examples":[{"de":"Die alte Münze ist leider wertlos.","en":"The old coin is unfortunately worthless.","ru":"Старая монета, к сожалению, ничего не стоит.","vi":"Thật không may, đồng tiền cũ không có giá trị.","fa":"متأسفانه سکه قدیمی بی ارزش است."},{"de":"Ohne Unterschrift ist der Vertrag wertlos.","en":"Without a signature the contract is worthless.","ru":"Без подписи договор недействителен.","vi":"Nếu không có chữ ký, hợp đồng sẽ vô giá trị.","fa":"بدون امضا، قرارداد بی ارزش است."},{"de":"Er fühlte sich nach der Kündigung wertlos.","en":"He felt worthless after being made redundant.","ru":"После увольнения он чувствовал себя никчёмным.","vi":"Anh cảm thấy mình vô dụng sau khi bị sa thải.","fa":"او پس از اخراج احساس بی ارزشی می کرد."}]},{"word":"wertvoll","en":"valuable, precious","ru":"ценный, драгоценный","vi":"có giá trị","fa":"با ارزش","examples":[{"de":"Dieser Ring ist sehr wertvoll.","en":"This ring is very valuable.","ru":"Это кольцо очень ценное.","vi":"Chiếc nhẫn này rất có giá trị.","fa":"این انگشتر بسیار ارزشمند است."},{"de":"Deine Hilfe war für uns sehr wertvoll.","en":"Your help was very valuable to us.","ru":"Твоя помощь была для нас очень ценной.","vi":"Sự giúp đỡ của bạn rất có giá trị đối với chúng tôi.","fa":"کمک شما برای ما بسیار ارزشمند بود."},{"de":"Im Museum hängen viele wertvolle Gemälde.","en":"Many valuable paintings hang in the museum.","ru":"В музее висит много ценных картин.","vi":"Có rất nhiều bức tranh có giá trị được treo trong bảo tàng.","fa":"تابلوهای با ارزش زیادی در این موزه آویزان است."}]},{"word":"wesentlich","en":"essential; considerably","ru":"существенный; значительно","vi":"thiết yếu","fa":"ضروری است","examples":[{"de":"Das ist ein wesentlicher Unterschied.","en":"That is an essential difference.","ru":"Это существенное различие.","vi":"Đó là một sự khác biệt quan trọng.","fa":"این یک تفاوت کلیدی است."},{"de":"Heute geht es mir wesentlich besser.","en":"I feel considerably better today.","ru":"Сегодня мне значительно лучше.","vi":"Hôm nay tôi cảm thấy tốt hơn nhiều rồi.","fa":"امروز حالم خیلی بهتر است."}]},{"word":"weshalb","en":"why","ru":"почему, по какой причине","vi":"tại sao","fa":"چرا","examples":[{"de":"Weshalb bist du so spät gekommen?","en":"Why did you come so late?","ru":"Почему ты пришёл так поздно?","vi":"Tại sao bạn đến muộn thế?","fa":"چرا اینقدر دیر اومدی؟"},{"de":"Ich weiß nicht, weshalb er böse ist.","en":"I don't know why he's angry.","ru":"Я не знаю, почему он злится.","vi":"Tôi không biết tại sao anh ấy lại tức giận.","fa":"نمی دانم چرا عصبانی است."}]},{"word":"der Wettbewerb","en":"competition","ru":"конкурс, соревнование","vi":"cuộc thi","fa":"رقابت","examples":[{"de":"Sie hat den Wettbewerb gewonnen.","en":"She won the competition.","ru":"Она выиграла конкурс.","vi":"Cô ấy đã thắng cuộc thi.","fa":"او برنده مسابقه شد."},{"de":"An dem Wettbewerb nehmen viele Schüler teil.","en":"Many students take part in the competition.","ru":"В конкурсе участвует много учеников.","vi":"Nhiều sinh viên tham gia cuộc thi.","fa":"دانش آموزان زیادی در این مسابقه شرکت می کنند."}]},{"word":"wetten","en":"to bet","ru":"спорить, держать пари","vi":"cá cược","fa":"شرط بندی","examples":[{"de":"Ich wette, dass es morgen regnet.","en":"I bet it will rain tomorrow.","ru":"Спорим, завтра пойдёт дождь.","vi":"Tôi cá là ngày mai trời sẽ mưa.","fa":"شرط میبندم فردا بارون میاد"},{"de":"Sie haben um zehn Euro gewettet.","en":"They bet ten euros.","ru":"Они поспорили на десять евро.","vi":"Bạn đặt cược mười euro.","fa":"ده یورو شرط کردی"}]},{"word":"das Wetter","en":"weather","ru":"погода","vi":"thời tiết","fa":"آب و هوا","examples":[{"de":"Das Wetter ist heute wunderschön.","en":"The weather is beautiful today.","ru":"Сегодня прекрасная погода.","vi":"Thời tiết hôm nay thật đẹp.","fa":"هوا امروز قشنگه"},{"de":"Bei schlechtem Wetter bleiben wir drinnen.","en":"In bad weather we stay indoors.","ru":"В плохую погоду мы остаёмся дома.","vi":"Nếu thời tiết xấu, chúng tôi ở trong nhà.","fa":"اگر هوا بد باشد داخل می مانیم."}]},{"word":"die Wettervorhersage","en":"weather forecast","ru":"прогноз погоды","vi":"dự báo thời tiết","fa":"پیش بینی آب و هوا","examples":[{"de":"Laut Wettervorhersage wird es morgen sonnig.","en":"According to the weather forecast, it will be sunny tomorrow.","ru":"Согласно прогнозу погоды, завтра будет солнечно.","vi":"Theo dự báo thời tiết thì ngày mai trời sẽ nắng.","fa":"طبق پیش بینی هواشناسی فردا هوا آفتابی خواهد بود."},{"de":"Ich schaue jeden Abend die Wettervorhersage.","en":"I watch the weather forecast every evening.","ru":"Я каждый вечер смотрю прогноз погоды.","vi":"Tôi kiểm tra dự báo thời tiết vào mỗi buổi tối.","fa":"من هر شب پیش بینی آب و هوا را چک می کنم."}]},{"word":"die Wettervorhersage hören","en":"to listen to the weather forecast","ru":"слушать прогноз погоды","vi":"nghe dự báo thời tiết","fa":"پیش بینی آب و هوا را بشنوید","examples":[{"de":"Jeden Morgen höre ich die Wettervorhersage im Radio.","en":"Every morning I listen to the weather forecast on the radio.","ru":"Каждое утро я слушаю прогноз погоды по радио.","vi":"Mỗi buổi sáng tôi nghe dự báo thời tiết trên radio.","fa":"هر روز صبح از رادیو به پیش بینی هواشناسی گوش می دهم."},{"de":"Hast du heute schon die Wettervorhersage gehört?","en":"Have you already listened to the weather forecast today?","ru":"Ты уже слушал сегодня прогноз погоды?","vi":"Bạn đã nghe dự báo thời tiết hôm nay chưa?","fa":"آیا پیش بینی هوای امروز را شنیده اید؟"},{"de":"Wir sollten die Wettervorhersage hören, bevor wir wandern gehen.","en":"We should listen to the weather forecast before we go hiking.","ru":"Нам стоит послушать прогноз погоды, прежде чем идти в поход.","vi":"Chúng ta nên nghe dự báo thời tiết trước khi đi leo núi.","fa":"قبل از پیاده روی باید به پیش بینی آب و هوا گوش کنیم."}]},{"word":"die Wettervorhersage-App","en":"weather forecast app","ru":"приложение с прогнозом погоды","vi":"ứng dụng dự báo thời tiết","fa":"برنامه پیش بینی آب و هوا","examples":[{"de":"Laut der Wettervorhersage-App soll es morgen regnen.","en":"According to the weather forecast app it is supposed to rain tomorrow.","ru":"Согласно приложению с прогнозом погоды, завтра должен пойти дождь.","vi":"Theo ứng dụng dự báo thời tiết, ngày mai trời sẽ mưa.","fa":"طبق برنامه پیش بینی هواشناسی، قرار است فردا باران ببارد."},{"de":"Ich vertraue dieser Wettervorhersage-App nicht ganz.","en":"I do not fully trust this weather forecast app.","ru":"Я не совсем доверяю этому приложению с прогнозом погоды.","vi":"Tôi không hoàn toàn tin tưởng ứng dụng dự báo thời tiết này.","fa":"من کاملاً به این برنامه پیش بینی آب و هوا اعتماد ندارم."},{"de":"Die Wettervorhersage-App zeigt jetzt auch die Windrichtung.","en":"The weather forecast app now also shows the wind direction.","ru":"Приложение с прогнозом погоды теперь показывает и направление ветра.","vi":"Ứng dụng dự báo thời tiết giờ đây cũng hiển thị hướng gió.","fa":"اپلیکیشن پیش بینی آب و هوا اکنون جهت باد را نیز نشان می دهد."}]},{"word":"wichtig","en":"important","ru":"важный","vi":"quan trọng","fa":"مهم است","examples":[{"de":"Diese Entscheidung ist sehr wichtig für mich.","en":"This decision is very important to me.","ru":"Это решение очень важно для меня.","vi":"Quyết định này rất quan trọng đối với tôi.","fa":"این تصمیم برای من بسیار مهم است."},{"de":"Es ist wichtig, pünktlich zu sein.","en":"It's important to be punctual.","ru":"Важно быть пунктуальным.","vi":"Điều quan trọng là phải đúng giờ.","fa":"مهم این است که به موقع باشد."}]},{"word":"widerrufen","en":"to revoke, to withdraw, to cancel (e.g. a contract)","ru":"отзывать, отменять (напр. договор)","vi":"bị thu hồi","fa":"لغو شد","examples":[{"de":"Sie können den Vertrag innerhalb von zwei Wochen widerrufen.","en":"You can cancel the contract within two weeks.","ru":"Вы можете расторгнуть договор в течение двух недель.","vi":"Bạn có thể hủy hợp đồng trong vòng hai tuần.","fa":"می توانید ظرف دو هفته قرارداد را لغو کنید."},{"de":"Er hat seine Aussage später widerrufen.","en":"He later retracted his statement.","ru":"Позже он отозвал своё заявление.","vi":"Sau đó ông đã rút lại tuyên bố của mình.","fa":"او بعداً اظهارات خود را پس گرفت."},{"de":"Die Bank hat die Vollmacht widerrufen.","en":"The bank revoked the authorisation.","ru":"Банк отозвал доверенность.","vi":"Ngân hàng đã thu hồi giấy ủy quyền.","fa":"بانک وکالت نامه را باطل کرده است."}]},{"word":"widersprechen","en":"to contradict","ru":"противоречить","vi":"mâu thuẫn","fa":"تناقض دارند","examples":[{"de":"Er widerspricht seinem Chef nie.","en":"He never contradicts his boss.","ru":"Он никогда не противоречит своему начальнику.","vi":"Anh ấy không bao giờ mâu thuẫn với sếp của mình.","fa":"او هرگز با رئیس خود مخالفت نمی کند."},{"de":"Diese Aussage widerspricht den Fakten.","en":"This statement contradicts the facts.","ru":"Это заявление противоречит фактам.","vi":"Tuyên bố này mâu thuẫn với sự thật.","fa":"این گفته با واقعیت ها تناقض دارد."}]},{"word":"wie","en":"how; as, like","ru":"как","vi":"thích","fa":"مانند","examples":[{"de":"Wie geht es dir?","en":"How are you?","ru":"Как дела?","vi":"Bạn dạo này thế nào?","fa":"حال شما چطور است؟"},{"de":"Sie singt wie eine Profisängerin.","en":"She sings like a professional singer.","ru":"Она поёт как профессиональная певица.","vi":"Cô ấy hát như một ca sĩ chuyên nghiệp.","fa":"او مانند یک خواننده حرفه ای می خواند."}]},{"word":"wie ein Elefant im Porzellanladen","en":"like a bull in a china shop (clumsy)","ru":"как слон в посудной лавке (неуклюже)","vi":"như con bò đực trong cửa hàng đồ sứ","fa":"مثل گاو نر در مغازه چینی فروشی","examples":[{"de":"Er benimmt sich manchmal wie ein Elefant im Porzellanladen.","en":"He sometimes behaves like a bull in a china shop.","ru":"Иногда он ведёт себя как слон в посудной лавке.","vi":"Đôi khi anh ấy cư xử như một con bò đực trong một cửa hàng đồ sứ.","fa":"او گاهی اوقات مانند یک گاو نر در یک مغازه چینی رفتار می کند."}]},{"word":"Wie meinst du das genau?","en":"What exactly do you mean? (asking for clarification)","ru":"Что именно ты имеешь в виду? (уточнение)","vi":"Chính xác thì ý bạn là gì?","fa":"منظورت دقیقا چیه؟","examples":[{"de":"Wie meinst du das genau? Das habe ich nicht verstanden.","en":"What exactly do you mean? I didn't understand that.","ru":"Что именно ты имеешь в виду? Я не понял.","vi":"Chính xác thì ý bạn là gì? Tôi không hiểu.","fa":"منظورت دقیقا چیه؟ من متوجه نشدم."}]},{"word":"wie viel(e)","en":"how much; how many","ru":"сколько","vi":"bao nhiêu","fa":"چقدر(ها)","examples":[{"de":"Wie viel kostet das Ticket?","en":"How much does the ticket cost?","ru":"Сколько стоит билет?","vi":"Giá vé là bao nhiêu?","fa":"هزینه بلیط چقدر است؟"},{"de":"Wie viele Geschwister hast du?","en":"How many siblings do you have?","ru":"Сколько у тебя братьев и сестёр?","vi":"Bạn có bao nhiêu anh chị em?","fa":"چند تا خواهر و برادر داری؟"}]},{"word":"Wie wäre es mit …?","en":"How about …? (suggestion)","ru":"Как насчёт …? (предложение)","vi":"Bạn nghĩ thế nào về …?","fa":"چطور…؟","examples":[{"de":"Wie wäre es mit einem Picknick im Park?","en":"How about a picnic in the park?","ru":"Как насчёт пикника в парке?","vi":"Thế còn một chuyến dã ngoại trong công viên thì sao?","fa":"پیک نیک در پارک چطور؟"}]},{"word":"wieder","en":"again","ru":"снова, опять","vi":"một lần nữa","fa":"دوباره","examples":[{"de":"Er kommt morgen wieder.","en":"He's coming again tomorrow.","ru":"Он снова придёт завтра.","vi":"Anh ấy sẽ quay lại vào ngày mai.","fa":"فردا برمیگرده"},{"de":"Ich habe meinen Schlüssel wieder gefunden.","en":"I found my key again.","ru":"Я снова нашёл свой ключ.","vi":"Tôi lại tìm thấy chìa khóa của mình.","fa":"دوباره کلیدم را پیدا کردم."}]},{"word":"wieder-","en":"again, re- (separable prefix meaning repetition)","ru":"снова, пере- (отделяемая приставка со значением повтора)","vi":"lại-","fa":"دوباره-","examples":[{"de":"Ich rufe dich später wieder an.","en":"I'll call you back again later.","ru":"Я перезвоню тебе позже.","vi":"Tôi sẽ gọi lại cho bạn sau.","fa":"بعدا دوباره بهت زنگ میزنم"},{"de":"Bitte wiederhole den Satz noch einmal.","en":"Please repeat the sentence once more.","ru":"Повтори, пожалуйста, предложение ещё раз.","vi":"Hãy lặp lại câu đó một lần nữa.","fa":"لطفا دوباره جمله را تکرار کنید."},{"de":"Wir sehen uns morgen wieder.","en":"We'll see each other again tomorrow.","ru":"Мы снова увидимся завтра.","vi":"Chúng ta sẽ gặp lại nhau vào ngày mai.","fa":"فردا دوباره همدیگر را می بینیم."}]},{"word":"wiederholen","en":"to repeat","ru":"повторять","vi":"lặp lại","fa":"تکرار کنید","examples":[{"de":"Können Sie die Frage bitte wiederholen?","en":"Could you please repeat the question?","ru":"Не могли бы вы повторить вопрос?","vi":"Bạn có thể vui lòng lặp lại câu hỏi được không?","fa":"میشه لطفا سوال رو تکرار کنید"},{"de":"Wir wiederholen den Wortschatz vor der Prüfung.","en":"We're reviewing the vocabulary before the exam.","ru":"Мы повторяем словарный запас перед экзаменом.","vi":"Chúng tôi ôn lại từ vựng trước kỳ thi.","fa":"قبل از امتحان دایره لغات را مرور می کنیم."}]},{"word":"die Wiederholung","en":"repetition; repeat (broadcast); revision","ru":"повторение; повтор (передачи)","vi":"sự lặp lại","fa":"تکرار","examples":[{"de":"Vor der Prüfung ist eine Wiederholung des Stoffes wichtig.","en":"Before the exam, revision of the material is important.","ru":"Перед экзаменом важно повторение материала.","vi":"Điều quan trọng là phải lặp lại tài liệu trước kỳ thi.","fa":"تکرار مطالب قبل از امتحان مهم است."},{"de":"Heute Abend kommt nur eine Wiederholung im Fernsehen.","en":"There's only a repeat on TV this evening.","ru":"Сегодня вечером по телевизору только повтор.","vi":"Chỉ có một chương trình lặp lại trên TV tối nay.","fa":"امشب فقط یک تکرار در تلویزیون وجود دارد."},{"de":"Durch ständige Wiederholung lernt man neue Wörter.","en":"You learn new words through constant repetition.","ru":"Благодаря постоянному повторению учат новые слова.","vi":"Bạn học từ mới thông qua việc lặp lại liên tục.","fa":"با تکرار مداوم کلمات جدید را یاد می گیرید."}]},{"word":"die Wiedervereinigung","en":"reunification","ru":"воссоединение, объединение (Германии)","vi":"sự thống nhất","fa":"the reunification","examples":[{"de":"Die deutsche Wiedervereinigung fand 1990 statt.","en":"German reunification took place in 1990.","ru":"Объединение Германии произошло в 1990 году.","vi":"Sự thống nhất nước Đức diễn ra vào năm 1990.","fa":"اتحاد مجدد آلمان در سال 1990 اتفاق افتاد."},{"de":"Nach der Wiedervereinigung wuchs das Land langsam zusammen.","en":"After reunification the country slowly grew back together.","ru":"После воссоединения страна медленно срасталась.","vi":"Sau khi thống nhất, đất nước dần cùng nhau lớn mạnh.","fa":"پس از اتحاد مجدد، کشور به آرامی با هم رشد کرد."},{"de":"Viele Familien feierten die Wiedervereinigung mit Tränen.","en":"Many families celebrated reunification with tears.","ru":"Многие семьи праздновали воссоединение со слезами.","vi":"Nhiều gia đình đón đoàn tụ trong nước mắt.","fa":"بسیاری از خانواده ها این دیدار را با گریه جشن گرفتند."}]},{"word":"wiegen","en":"to weigh","ru":"весить, взвешивать","vi":"cân","fa":"وزن کردن","examples":[{"de":"Das Paket wiegt zwei Kilo.","en":"The package weighs two kilos.","ru":"Посылка весит два килограмма.","vi":"Gói hàng nặng hai kg.","fa":"وزن بسته دو کیلو می باشد."},{"de":"Der Verkäufer wiegt das Obst.","en":"The seller weighs the fruit.","ru":"Продавец взвешивает фрукты.","vi":"Người bán cân trái cây.","fa":"فروشنده میوه را وزن می کند."}]},{"word":"die Wiese","en":"meadow","ru":"луг","vi":"đồng cỏ","fa":"چمنزار","examples":[{"de":"Die Kühe stehen auf der Wiese.","en":"The cows are standing in the meadow.","ru":"Коровы стоят на лугу.","vi":"Những con bò đang đứng trên đồng cỏ.","fa":"گاوها در چمنزار ایستاده اند."},{"de":"Wir haben auf der Wiese gepicknickt.","en":"We had a picnic in the meadow.","ru":"Мы устроили пикник на лугу.","vi":"Chúng tôi đã có một buổi dã ngoại trên bãi cỏ.","fa":"ما یک پیک نیک روی چمن داشتیم."}]},{"word":"wieso","en":"why","ru":"почему","vi":"sao thế","fa":"چرا","examples":[{"de":"Wieso hast du das getan?","en":"Why did you do that?","ru":"Почему ты это сделал?","vi":"Tại sao bạn làm điều đó?","fa":"چرا این کار را کردی؟"},{"de":"Wieso kommst du nicht mit?","en":"Why aren't you coming along?","ru":"Почему ты не идёшь с нами?","vi":"Tại sao bạn không đi cùng tôi?","fa":"چرا با من نمی آیی؟"}]},{"word":"wild","en":"wild","ru":"дикий","vi":"hoang dã","fa":"وحشی","examples":[{"de":"Im Park leben wilde Tiere.","en":"Wild animals live in the park.","ru":"В парке живут дикие животные.","vi":"Động vật hoang dã sống trong công viên.","fa":"حیوانات وحشی در پارک زندگی می کنند."},{"de":"Die Kinder spielten wild im Garten.","en":"The children played wildly in the garden.","ru":"Дети дико резвились в саду.","vi":"Bọn trẻ đang chơi đùa trong vườn.","fa":"بچه ها در باغ وحشی بازی می کردند."}]},{"word":"willkommen","en":"welcome","ru":"добро пожаловать","vi":"chào mừng","fa":"خوش آمدید","examples":[{"de":"Herzlich willkommen in unserem Haus!","en":"Warm welcome to our house!","ru":"Добро пожаловать в наш дом!","vi":"Chào mừng đến với ngôi nhà của chúng tôi!","fa":"به خانه ما خوش آمدید!"},{"de":"Neue Mitarbeiter sind immer willkommen.","en":"New employees are always welcome.","ru":"Новые сотрудники всегда желанны.","vi":"Nhân viên mới luôn được chào đón.","fa":"کارکنان جدید همیشه خوش آمدید."}]},{"word":"der Wind","en":"wind","ru":"ветер","vi":"gió","fa":"باد","examples":[{"de":"Draußen weht ein starker Wind.","en":"A strong wind is blowing outside.","ru":"На улице дует сильный ветер.","vi":"Một cơn gió mạnh đang thổi bên ngoài.","fa":"در بیرون باد شدیدی می وزد."},{"de":"Der Wind hat den Regenschirm zerstört.","en":"The wind destroyed the umbrella.","ru":"Ветер сломал зонт.","vi":"Gió đã phá hủy chiếc ô.","fa":"باد چتر را خراب کرد."}]},{"word":"das Windrad","en":"wind turbine","ru":"ветряк, ветрогенератор","vi":"tuabin gió","fa":"توربین بادی","examples":[{"de":"Auf dem Feld hinter dem Dorf stehen viele Windräder.","en":"There are many wind turbines in the field behind the village.","ru":"На поле за деревней стоит много ветряков.","vi":"Có rất nhiều tua-bin gió ở cánh đồng phía sau làng.","fa":"توربین های بادی زیادی در زمین پشت روستا وجود دارد."},{"de":"Ein einziges Windrad kann viele Haushalte mit Strom versorgen.","en":"A single wind turbine can supply many households with electricity.","ru":"Один-единственный ветряк может обеспечить электричеством много домов.","vi":"Một tuabin gió có thể cung cấp điện cho nhiều hộ gia đình.","fa":"یک توربین بادی واحد می تواند برق بسیاری از خانوارها را تامین کند."},{"de":"Windräder erzeugen saubere Energie ohne schädliche Abgase.","en":"Wind turbines generate clean energy without harmful emissions.","ru":"Ветряки производят чистую энергию без вредных выбросов.","vi":"Tua bin gió tạo ra năng lượng sạch mà không phát thải độc hại.","fa":"توربین های بادی انرژی پاکی را بدون انتشارات مضر تولید می کنند."}]},{"word":"winken","en":"to wave","ru":"махать","vi":"làn sóng","fa":"موج","examples":[{"de":"Die Kinder winken dem Zug hinterher.","en":"The children wave after the train.","ru":"Дети машут вслед поезду.","vi":"Những đứa trẻ vẫy tay sau chuyến tàu.","fa":"بچه ها بعد از قطار دست تکان می دهند."},{"de":"Sie winkte mir vom Fenster aus zu.","en":"She waved to me from the window.","ru":"Она помахала мне из окна.","vi":"Cô ấy vẫy tay chào tôi từ cửa sổ.","fa":"از پنجره برایم دست تکان داد."}]},{"word":"der Winterdienst","en":"winter road service (gritting/snow clearing)","ru":"зимняя дорожная служба (уборка снега и посыпка)","vi":"dịch vụ mùa đông","fa":"سرویس زمستانی","examples":[{"de":"Der Winterdienst hat heute Nacht die Straßen geräumt.","en":"The winter road service cleared the roads last night.","ru":"Зимняя дорожная служба этой ночью расчистила улицы.","vi":"Buổi lễ mùa đông tối nay đã dọn sạch đường phố.","fa":"سرویس زمستانی امشب خیابان ها را پاکسازی کرد."},{"de":"Bei Schnee muss der Winterdienst früh aufstehen.","en":"When it snows, the winter road service has to get up early.","ru":"Когда идёт снег, зимней службе приходится вставать рано.","vi":"Khi tuyết rơi, dịch vụ mùa đông phải dậy sớm.","fa":"وقتی برف می بارد، سرویس زمستانی باید زود بیدار شود."},{"de":"Als Mieter sind wir für den Winterdienst auf dem Gehweg zuständig.","en":"As tenants we are responsible for clearing snow from the pavement.","ru":"Как арендаторы мы отвечаем за уборку снега на тротуаре.","vi":"Với tư cách là người thuê nhà, chúng tôi chịu trách nhiệm bảo trì vỉa hè vào mùa đông.","fa":"ما به عنوان مستاجر، مسئول نگهداری زمستانی پیاده رو هستیم."}]},{"word":"Wir könnten …","en":"We could … (suggestion, planning)","ru":"Мы могли бы … (предложение)","vi":"Chúng tôi có thể…","fa":"ما می توانستیم…","examples":[{"de":"Wir könnten am Samstag ins Museum gehen.","en":"We could go to the museum on Saturday.","ru":"Мы могли бы в субботу сходить в музей.","vi":"Chúng ta có thể đến bảo tàng vào thứ bảy.","fa":"شنبه می توانستیم به موزه برویم."}]},{"word":"die Wirbelsäule","en":"spine","ru":"позвоночник","vi":"cột sống","fa":"ستون فقرات","examples":[{"de":"Halte die Wirbelsäule gerade, während du sitzt.","en":"Keep your spine straight while you sit.","ru":"Держи позвоночник прямым, пока сидишь.","vi":"Giữ cột sống thẳng khi ngồi.","fa":"هنگام نشستن ستون فقرات خود را صاف نگه دارید."},{"de":"Diese Übung macht die Wirbelsäule beweglicher.","en":"This exercise makes the spine more flexible.","ru":"Это упражнение делает позвоночник подвижнее.","vi":"Bài tập này giúp cột sống linh hoạt hơn.","fa":"این تمرین باعث انعطاف بیشتر ستون فقرات می شود."},{"de":"Beim Vorbeugen rollst du die Wirbelsäule Wirbel für Wirbel ab.","en":"When bending forward, you roll down the spine vertebra by vertebra.","ru":"При наклоне вперёд ты раскручиваешь позвоночник позвонок за позвонком.","vi":"Khi bạn cúi người về phía trước, bạn cuộn cột sống của mình từng đốt sống một.","fa":"وقتی به جلو خم می‌شوید، مهره‌های خود را یکی یکی می‌چرخانید."}]},{"word":"die Wirbelsäulendrehung","en":"spinal twist","ru":"скручивание позвоночника","vi":"sự xoay cột sống","fa":"چرخش ستون فقرات","examples":[{"de":"Wir machen am Ende eine sanfte Wirbelsäulendrehung im Liegen.","en":"At the end we do a gentle spinal twist while lying down.","ru":"В конце мы делаем мягкое скручивание позвоночника лёжа.","vi":"Cuối cùng, chúng ta thực hiện động tác vặn cột sống nhẹ nhàng trong khi nằm.","fa":"در انتها در حالی که دراز کشیده اید یک چرخش ستون فقرات را انجام می دهیم."},{"de":"Die Wirbelsäulendrehung löst Verspannungen im unteren Rücken.","en":"The spinal twist releases tension in the lower back.","ru":"Скручивание позвоночника снимает напряжение в пояснице.","vi":"Xoay cột sống làm giảm căng thẳng ở lưng dưới.","fa":"چرخش ستون فقرات تنش را در قسمت پایین کمر کاهش می دهد."},{"de":"Atme bei der Wirbelsäulendrehung ruhig weiter.","en":"Keep breathing calmly during the spinal twist.","ru":"Во время скручивания позвоночника продолжай спокойно дышать.","vi":"Tiếp tục thở bình tĩnh khi bạn vặn cột sống.","fa":"در حالی که ستون فقرات خود را می پیچید به آرامی به تنفس خود ادامه دهید."}]},{"word":"wirken","en":"to seem, appear; to have an effect","ru":"казаться; действовать (об эффекте)","vi":"có vẻ; có tác dụng","fa":"به نظر رسیدن؛ تأثیر گذاشتن","examples":[{"de":"Er wirkte heute sehr müde.","en":"He seemed very tired today.","ru":"Сегодня он казался очень уставшим.","vi":"Hôm nay anh có vẻ rất mệt mỏi.","fa":"امروز خیلی خسته به نظر می رسید."},{"de":"Die Medizin wirkt schnell.","en":"The medicine works quickly.","ru":"Лекарство действует быстро.","vi":"Thuốc có tác dụng nhanh chóng.","fa":"دارو به سرعت عمل می کند."}]},{"word":"wirklich","en":"really","ru":"действительно, правда","vi":"thực sự","fa":"واقعا","examples":[{"de":"Das ist wirklich eine gute Idee.","en":"That's really a good idea.","ru":"Это действительно хорошая идея.","vi":"Đó thực sự là một ý tưởng tốt.","fa":"این یک ایده واقعا خوب است."},{"de":"Ist das wirklich passiert?","en":"Did that really happen?","ru":"Это действительно произошло?","vi":"Điều đó có thực sự xảy ra không?","fa":"واقعا این اتفاق افتاد؟"}]},{"word":"die Wirklichkeit","en":"reality","ru":"действительность, реальность","vi":"sự thật","fa":"واقعیت","examples":[{"de":"In Wirklichkeit ist alles ganz anders.","en":"In reality everything is quite different.","ru":"На самом деле всё совсем иначе.","vi":"Trong thực tế mọi thứ hoàn toàn khác nhau.","fa":"در واقعیت همه چیز کاملاً متفاوت است."},{"de":"Sein Traum wurde endlich Wirklichkeit.","en":"His dream finally became reality.","ru":"Его мечта наконец стала реальностью.","vi":"Ước mơ của anh cuối cùng đã trở thành hiện thực.","fa":"رویای او سرانجام به واقعیت تبدیل شد."},{"de":"Die Wirklichkeit sieht oft härter aus als im Film.","en":"Reality often looks harder than in the film.","ru":"Действительность часто выглядит суровее, чем в кино.","vi":"Thực tế thường có vẻ khắc nghiệt hơn trong phim.","fa":"واقعیت اغلب خشن تر از فیلم ها به نظر می رسد."}]},{"word":"die Wirkung","en":"effect; impact","ru":"действие, эффект, воздействие","vi":"hiệu ứng","fa":"اثر","examples":[{"de":"Das Medikament zeigt schnell seine Wirkung.","en":"The medicine quickly shows its effect.","ru":"Лекарство быстро оказывает своё действие.","vi":"Thuốc có tác dụng nhanh chóng.","fa":"دارو به سرعت اثر می گذارد."},{"de":"Seine Worte hatten eine große Wirkung auf uns.","en":"His words had a great effect on us.","ru":"Его слова оказали на нас большое воздействие.","vi":"Lời nói của anh ấy đã có tác động lớn đến chúng tôi.","fa":"حرف های او تاثیر زیادی روی ما گذاشت."},{"de":"Der Kaffee hat bei mir kaum noch Wirkung.","en":"Coffee hardly has any effect on me any more.","ru":"Кофе почти уже не оказывает на меня действия.","vi":"Cà phê hầu như không còn tác dụng gì với tôi nữa.","fa":"قهوه دیگر هیچ تاثیری روی من ندارد."}]},{"word":"der Wirt","en":"host, innkeeper","ru":"хозяин (трактира), трактирщик","vi":"chủ nhà","fa":"میزبان","examples":[{"de":"Der Wirt begrüßte uns freundlich.","en":"The innkeeper greeted us kindly.","ru":"Хозяин трактира приветливо нас встретил.","vi":"Người chủ quán chào đón chúng tôi thân thiện.","fa":"صاحب مسافرخانه با دوستانه از ما استقبال کرد."},{"de":"Wir fragten den Wirt nach der Speisekarte.","en":"We asked the innkeeper for the menu.","ru":"Мы спросили хозяина о меню.","vi":"Chúng tôi hỏi chủ quán về thực đơn.","fa":"از مسافرخانه داری منو خواستیم."}]},{"word":"die Wirtin","en":"landlady; innkeeper (female); host","ru":"трактирщица, хозяйка заведения","vi":"bà chủ nhà","fa":"خانم صاحبخانه","examples":[{"de":"Die Wirtin servierte uns einen warmen Apfelstrudel.","en":"The landlady served us a warm apple strudel.","ru":"Хозяйка подала нам тёплый яблочный штрудель.","vi":"Bà chủ nhà phục vụ chúng tôi món bánh strudel táo ấm.","fa":"خانم صاحبخانه یک اشترودل سیب گرم برایمان سرو کرد."},{"de":"Unsere Wirtin ist immer freundlich zu den Gästen.","en":"Our landlady is always friendly to the guests.","ru":"Наша хозяйка всегда приветлива с гостями.","vi":"Bà chủ nhà của chúng tôi luôn thân thiện với khách.","fa":"خانم صاحبخانه ما همیشه با مهمانان مهربان است."},{"de":"Die Wirtin erzählte uns viel über das alte Gasthaus.","en":"The landlady told us a lot about the old inn.","ru":"Хозяйка много рассказала нам о старом трактире.","vi":"Bà chủ nhà kể cho chúng tôi rất nhiều điều về quán trọ cũ.","fa":"خانم صاحبخانه از مسافرخانه قدیمی خیلی به ما گفت."}]},{"word":"die Wirtschaft","en":"economy","ru":"экономика","vi":"nền kinh tế","fa":"اقتصاد","examples":[{"de":"Die Wirtschaft wächst in diesem Jahr stark.","en":"The economy is growing strongly this year.","ru":"В этом году экономика сильно растёт.","vi":"Nền kinh tế đang phát triển mạnh mẽ trong năm nay.","fa":"اقتصاد امسال به شدت در حال رشد است."},{"de":"Viele Menschen arbeiten in der Wirtschaft des Landes.","en":"Many people work in the country's economy.","ru":"Многие люди работают в экономике страны.","vi":"Nhiều người làm việc trong nền kinh tế của đất nước.","fa":"افراد زیادی در اقتصاد کشور کار می کنند."}]},{"word":"wissen","en":"to know","ru":"знать","vi":"biết","fa":"دانستن","examples":[{"de":"Ich weiß die Antwort nicht.","en":"I don't know the answer.","ru":"Я не знаю ответа.","vi":"Tôi không biết câu trả lời.","fa":"من جواب را نمی دانم."},{"de":"Weißt du, wo der Bahnhof ist?","en":"Do you know where the station is?","ru":"Ты знаешь, где вокзал?","vi":"Bạn có biết nhà ga xe lửa ở đâu không?","fa":"آیا می دانید ایستگاه قطار کجاست؟"}]},{"word":"die Wissenschaft","en":"science","ru":"наука","vi":"khoa học","fa":"علم","examples":[{"de":"Die Wissenschaft hat große Fortschritte gemacht.","en":"Science has made great progress.","ru":"Наука сделала большие успехи.","vi":"Khoa học đã có những tiến bộ vượt bậc.","fa":"علم پیشرفت زیادی کرده است."},{"de":"Sie interessiert sich sehr für Wissenschaft.","en":"She's very interested in science.","ru":"Она очень интересуется наукой.","vi":"Cô ấy rất quan tâm đến khoa học.","fa":"او علاقه زیادی به علم دارد."}]},{"word":"der Wissenschaftler","en":"scientist (male)","ru":"учёный (мужчина)","vi":"nhà khoa học","fa":"دانشمند","examples":[{"de":"Der Wissenschaftler forscht seit Jahren an dieser Frage.","en":"The scientist has been researching this question for years.","ru":"Учёный уже много лет исследует этот вопрос.","vi":"Nhà khoa học đã nghiên cứu câu hỏi này trong nhiều năm.","fa":"این دانشمند سال هاست که روی این سوال تحقیق کرده است."},{"de":"Ein bekannter Wissenschaftler hielt einen Vortrag.","en":"A well-known scientist gave a lecture.","ru":"Известный учёный прочитал доклад.","vi":"Một nhà khoa học nổi tiếng đã giảng bài.","fa":"یک دانشمند معروف سخنرانی کرد."},{"de":"Wissenschaftler haben ein neues Medikament entwickelt.","en":"Scientists have developed a new medicine.","ru":"Учёные разработали новое лекарство.","vi":"Các nhà khoa học đã phát triển một loại thuốc mới.","fa":"دانشمندان داروی جدیدی ساخته اند."}]},{"word":"die Wissenschaftlerin","en":"female scientist","ru":"учёная, женщина-учёный","vi":"nhà khoa học","fa":"دانشمند","examples":[{"de":"Die Wissenschaftlerin forscht an einer neuen Impfung.","en":"The scientist is researching a new vaccine.","ru":"Учёная исследует новую вакцину.","vi":"Nhà khoa học đang nghiên cứu một loại vắc xin mới.","fa":"این دانشمند در حال تحقیق بر روی یک واکسن جدید است."},{"de":"Eine bekannte Wissenschaftlerin hielt den Vortrag.","en":"A famous scientist gave the lecture.","ru":"Известная учёная прочитала лекцию.","vi":"Một nhà khoa học nổi tiếng đã giảng bài.","fa":"یک دانشمند معروف این سخنرانی را ایراد کرد."}]},{"word":"der Witz","en":"joke","ru":"шутка, анекдот","vi":"trò đùa","fa":"شوخی","examples":[{"de":"Er erzählt gern Witze.","en":"He likes telling jokes.","ru":"Он любит рассказывать анекдоты.","vi":"Anh ấy thích kể chuyện cười.","fa":"او دوست دارد جوک بگوید."},{"de":"Das war kein guter Witz.","en":"That wasn't a good joke.","ru":"Это была не очень удачная шутка.","vi":"Đó không phải là một trò đùa hay.","fa":"این شوخی خوبی نبود"}]},{"word":"wo","en":"where","ru":"где","vi":"ở đâu","fa":"کجا","examples":[{"de":"Wo wohnst du?","en":"Where do you live?","ru":"Где ты живёшь?","vi":"Bạn sống ở đâu?","fa":"شما کجا زندگی می کنید؟"},{"de":"Ich weiß nicht, wo meine Brille ist.","en":"I don't know where my glasses are.","ru":"Я не знаю, где мои очки.","vi":"Tôi không biết kính của tôi ở đâu.","fa":"نمیدونم عینکم کجاست"}]},{"word":"wöchentlich","en":"weekly","ru":"еженедельный","vi":"hàng tuần","fa":"هفتگی","examples":[{"de":"Die Zeitschrift erscheint wöchentlich.","en":"The magazine is published weekly.","ru":"Журнал выходит еженедельно.","vi":"Tạp chí được xuất bản hàng tuần.","fa":"این مجله به صورت هفتگی منتشر می شود."},{"de":"Wir haben ein wöchentliches Treffen am Montag.","en":"We have a weekly meeting on Monday.","ru":"У нас еженедельная встреча по понедельникам.","vi":"Chúng tôi có cuộc họp hàng tuần vào thứ Hai.","fa":"دوشنبه جلسه هفتگی داریم."},{"de":"Er bekommt sein Gehalt wöchentlich.","en":"He receives his wages weekly.","ru":"Он получает зарплату еженедельно.","vi":"Anh ấy nhận được tiền lương hàng tuần.","fa":"حقوق خود را به صورت هفتگی دریافت می کند."}]},{"word":"woher","en":"where from","ru":"откуда","vi":"từ đâu đến","fa":"از کجا","examples":[{"de":"Woher kommst du?","en":"Where are you from?","ru":"Откуда ты?","vi":"Bạn đến từ đâu?","fa":"شما از کجا می آیید؟"},{"de":"Woher weißt du das?","en":"How do you know that?","ru":"Откуда ты это знаешь?","vi":"Làm sao bạn biết điều đó?","fa":"شما از کجا می دانید؟"}]},{"word":"wohin","en":"where to","ru":"куда","vi":"ở đâu","fa":"کجا","examples":[{"de":"Wohin fährst du im Urlaub?","en":"Where are you going on vacation?","ru":"Куда ты едешь в отпуск?","vi":"Bạn đang đi đâu vào kỳ nghỉ?","fa":"تعطیلات کجا میری؟"},{"de":"Wohin hast du meine Schlüssel gelegt?","en":"Where did you put my keys?","ru":"Куда ты положил мои ключи?","vi":"Bạn đã để chìa khóa của tôi ở đâu?","fa":"کلیدهای مرا کجا گذاشتی؟"}]},{"word":"wohl","en":"probably; well","ru":"вероятно; хорошо","vi":"có lẽ","fa":"احتمالا","examples":[{"de":"Er ist wohl schon zu Hause.","en":"He's probably already home.","ru":"Он, наверное, уже дома.","vi":"Có lẽ anh ấy đã về nhà rồi.","fa":"او احتمالاً در خانه است."},{"de":"Fühlst du dich heute wohl?","en":"Do you feel well today?","ru":"Ты хорошо себя чувствуешь сегодня?","vi":"Hôm nay bạn có khỏe không?","fa":"آیا امروز احساس خوبی دارید؟"}]},{"word":"das Wohlbefinden","en":"well-being","ru":"самочувствие, благополучие","vi":"sự hạnh phúc","fa":"رفاه","examples":[{"de":"Regelmäßiges Yoga steigert mein allgemeines Wohlbefinden.","en":"Regular yoga increases my general well-being.","ru":"Регулярная йога улучшает моё общее самочувствие.","vi":"Tập yoga thường xuyên giúp cải thiện sức khỏe chung của tôi.","fa":"یوگای منظم باعث بهبود سلامت عمومی من می شود."},{"de":"Bewegung und Ruhe sind beide wichtig für das Wohlbefinden.","en":"Movement and rest are both important for well-being.","ru":"Движение и покой одинаково важны для самочувствия.","vi":"Tập thể dục và nghỉ ngơi đều quan trọng cho sức khỏe.","fa":"ورزش و استراحت هر دو برای تندرستی مهم هستند."},{"de":"Nach der Meditation spüre ich ein tiefes Wohlbefinden.","en":"After meditation I feel a deep sense of well-being.","ru":"После медитации я ощущаю глубокое благополучие.","vi":"Sau khi thiền tôi cảm thấy một cảm giác hạnh phúc sâu sắc.","fa":"بعد از مدیتیشن احساس خوبی دارم."}]},{"word":"wohnen","en":"to live, reside","ru":"жить, проживать","vi":"sống","fa":"زندگی می کنند","examples":[{"de":"Ich wohne seit fünf Jahren in Berlin.","en":"I've lived in Berlin for five years.","ru":"Я живу в Берлине уже пять лет.","vi":"Tôi đã sống ở Berlin được năm năm.","fa":"من پنج سال است که در برلین زندگی می کنم."},{"de":"Wo wohnt deine Familie?","en":"Where does your family live?","ru":"Где живёт твоя семья?","vi":"Gia đình bạn sống ở đâu?","fa":"خانواده شما کجا زندگی می کنند؟"}]},{"word":"die Wohngebäudeversicherung","en":"buildings insurance (residential property)","ru":"страхование жилого здания","vi":"bảo hiểm xây nhà","fa":"بیمه ساختمان خانه","examples":[{"de":"Als Hausbesitzer braucht man eine Wohngebäudeversicherung.","en":"As a homeowner you need buildings insurance.","ru":"Как владельцу дома нужно страхование жилого здания.","vi":"Là chủ nhà, bạn cần có bảo hiểm cho chủ nhà.","fa":"به عنوان یک صاحب خانه، به بیمه صاحب خانه نیاز دارید."},{"de":"Die Wohngebäudeversicherung zahlt bei Wasserschäden.","en":"The buildings insurance pays out for water damage.","ru":"Страхование здания выплачивает при повреждении водой.","vi":"Bảo hiểm chủ nhà chi trả trong trường hợp thiệt hại do nước gây ra.","fa":"بیمه صاحبان خانه در صورت آسیب آب پرداخت می کند."},{"de":"Wir haben die Wohngebäudeversicherung gewechselt.","en":"We changed our buildings insurance.","ru":"Мы сменили страховую компанию для страхования здания.","vi":"Chúng tôi đã thay đổi bảo hiểm chủ nhà.","fa":"بیمه صاحب خانه را عوض کردیم."}]},{"word":"der Wohnort","en":"place of residence","ru":"место жительства","vi":"nơi cư trú","fa":"محل سکونت","examples":[{"de":"Bitte tragen Sie Ihren Wohnort in das Formular ein.","en":"Please enter your place of residence on the form.","ru":"Пожалуйста, укажите в бланке своё место жительства.","vi":"Vui lòng nhập nơi cư trú của bạn trong mẫu.","fa":"لطفا محل سکونت خود را در فرم وارد نمایید."},{"de":"Mein Wohnort ist eine kleine Stadt in Bayern.","en":"My place of residence is a small town in Bavaria.","ru":"Моё место жительства — небольшой город в Баварии.","vi":"Nơi ở của tôi là một thị trấn nhỏ ở Bavaria.","fa":"محل زندگی من یک شهر کوچک در بایرن است."},{"de":"Nach dem Umzug hat sie einen neuen Wohnort.","en":"After the move she has a new place of residence.","ru":"После переезда у неё новое место жительства.","vi":"Sau khi chuyển đi, cô có nơi ở mới.","fa":"پس از نقل مکان، او یک مکان جدید برای زندگی دارد."}]},{"word":"der Wohnsitz","en":"(legal/registered) place of residence; domicile","ru":"(официальное, зарегистрированное) место жительства, домициль","vi":"nơi cư trú","fa":"محل سکونت","examples":[{"de":"Er hat seinen Wohnsitz in München angemeldet.","en":"He has registered his place of residence in Munich.","ru":"Он зарегистрировал место жительства в Мюнхене.","vi":"Anh ấy đã đăng ký cư trú tại Munich.","fa":"وی اقامت خود را در مونیخ ثبت کرده است."},{"de":"Für die Steuer ist der Wohnsitz wichtig.","en":"The place of residence is important for tax purposes.","ru":"Для налогов важно место жительства.","vi":"Nơi cư trú rất quan trọng đối với thuế.","fa":"محل اقامت برای مالیات مهم است."},{"de":"Sie hat ihren ersten Wohnsitz im Ausland.","en":"Her primary place of residence is abroad.","ru":"Её основное место жительства находится за границей.","vi":"Nơi cư trú chính của cô là ở nước ngoài.","fa":"اقامتگاه اصلی او خارج از کشور است."}]},{"word":"die Wohnung","en":"flat; apartment","ru":"квартира","vi":"căn hộ","fa":"آپارتمان","examples":[{"de":"Wir suchen eine größere Wohnung im Zentrum.","en":"We are looking for a bigger flat in the centre.","ru":"Мы ищем квартиру побольше в центре.","vi":"Chúng tôi đang tìm một căn hộ lớn hơn ở trung tâm.","fa":"ما به دنبال یک آپارتمان بزرگتر در مرکز هستیم."},{"de":"Ihre Wohnung liegt im dritten Stock.","en":"Her flat is on the third floor.","ru":"Её квартира на третьем этаже.","vi":"Căn hộ của bạn ở trên tầng ba.","fa":"آپارتمان شما در طبقه سوم است."}]},{"word":"die Wolke","en":"cloud","ru":"облако","vi":"đám mây","fa":"ابر","examples":[{"de":"Am Himmel sind viele dunkle Wolken.","en":"There are many dark clouds in the sky.","ru":"В небе много тёмных облаков.","vi":"Trên bầu trời có rất nhiều đám mây đen.","fa":"ابرهای سیاه زیادی در آسمان وجود دارد."},{"de":"Die Wolken verdecken die Sonne.","en":"The clouds are hiding the sun.","ru":"Облака закрывают солнце.","vi":"Mây che khuất mặt trời.","fa":"ابرها خورشید را پنهان می کنند."}]},{"word":"die Wolle","en":"wool","ru":"шерсть","vi":"len","fa":"پشم","examples":[{"de":"Der Pullover ist aus reiner Wolle.","en":"The sweater is made of pure wool.","ru":"Свитер сделан из чистой шерсти.","vi":"Chiếc áo len được làm bằng len nguyên chất.","fa":"ژاکت از پشم خالص ساخته شده است."},{"de":"Meine Oma strickt gern mit Wolle.","en":"My grandma likes to knit with wool.","ru":"Моя бабушка любит вязать из шерсти.","vi":"Bà tôi thích đan len.","fa":"مادربزرگم دوست دارد با پشم ببافد."}]},{"word":"wollen","en":"to want","ru":"хотеть","vi":"muốn","fa":"خواستن","examples":[{"de":"Ich will heute Abend ins Kino gehen.","en":"I want to go to the cinema tonight.","ru":"Я хочу пойти в кино сегодня вечером.","vi":"Tôi muốn đi xem phim tối nay.","fa":"امشب میخوام برم سینما."},{"de":"Was willst du zum Geburtstag?","en":"What do you want for your birthday?","ru":"Что ты хочешь на день рождения?","vi":"Bạn muốn gì cho ngày sinh nhật của mình?","fa":"برای تولدت چی میخوای؟"}]},{"word":"Wollen wir …?","en":"Shall we …? (suggestion)","ru":"Давай(те) …? (предложение)","vi":"Chúng ta sẽ…?","fa":"آیا ما…؟","examples":[{"de":"Wollen wir zusammen kochen?","en":"Shall we cook together?","ru":"Давай приготовим вместе?","vi":"Chúng ta có muốn nấu ăn cùng nhau không?","fa":"میخوایم با هم آشپزی کنیم؟"}]},{"word":"das Wort","en":"word","ru":"слово","vi":"từ","fa":"کلمه","examples":[{"de":"Ich kenne dieses Wort nicht.","en":"I don't know this word.","ru":"Я не знаю этого слова.","vi":"Tôi không biết từ này.","fa":"من این کلمه را نمی دانم"},{"de":"Er hat nur wenige Worte gesagt.","en":"He said only a few words.","ru":"Он сказал лишь несколько слов.","vi":"Anh ấy chỉ nói vài lời thôi.","fa":"فقط چند کلمه گفت."}]},{"word":"das Wörterbuch","en":"dictionary","ru":"словарь","vi":"từ điển","fa":"فرهنگ لغت","examples":[{"de":"Schlag das Wort im Wörterbuch nach.","en":"Look the word up in the dictionary.","ru":"Посмотри слово в словаре.","vi":"Tra cứu từ trong từ điển.","fa":"کلمه را در فرهنگ لغت جستجو کنید."},{"de":"Ich benutze oft ein Wörterbuch auf meinem Handy.","en":"I often use a dictionary on my phone.","ru":"Я часто пользуюсь словарём в телефоне.","vi":"Tôi thường sử dụng từ điển trên điện thoại của mình.","fa":"من اغلب از دیکشنری در گوشی خود استفاده می کنم."},{"de":"In der Prüfung ist kein Wörterbuch erlaubt.","en":"No dictionary is allowed in the exam.","ru":"На экзамене словарь не разрешён.","vi":"Không được phép sử dụng từ điển trong kỳ thi.","fa":"هیچ دیکشنری در امتحان مجاز نیست."}]},{"word":"worüber","en":"about what","ru":"о чём","vi":"về cái gì","fa":"در مورد چه چیزی","examples":[{"de":"Worüber sprecht ihr gerade?","en":"What are you talking about right now?","ru":"О чём вы сейчас разговариваете?","vi":"Hiện tại bạn đang nói về điều gì?","fa":"در حال حاضر در مورد چه چیزی صحبت می کنید؟"},{"de":"Worüber hast du dich so gefreut?","en":"What were you so happy about?","ru":"Чему ты так обрадовался?","vi":"Bạn đã rất vui mừng về điều gì?","fa":"برای چی اینقدر خوشحال بودی؟"}]},{"word":"worum","en":"about what; regarding what","ru":"о чём, насчёт чего","vi":"thế còn","fa":"چه در مورد","examples":[{"de":"Worum geht es in dem Film?","en":"What is the movie about?","ru":"О чём этот фильм?","vi":"Bộ phim nói về cái gì?","fa":"فیلم درباره چیست؟"},{"de":"Worum bittest du mich?","en":"What are you asking me for?","ru":"О чём ты меня просишь?","vi":"Bạn đang hỏi tôi điều gì?","fa":"از من چه می خواهی؟"}]},{"word":"die Wunde","en":"wound","ru":"рана","vi":"vết thương","fa":"زخم","examples":[{"de":"Die Wunde am Bein muss verbunden werden.","en":"The wound on the leg needs to be bandaged.","ru":"Рану на ноге нужно перевязать.","vi":"Vết thương ở chân cần được băng bó.","fa":"زخم روی پا باید بانداژ شود."},{"de":"Die Wunde heilt langsam.","en":"The wound is healing slowly.","ru":"Рана заживает медленно.","vi":"Vết thương đang dần lành lại.","fa":"زخم کم کم خوب می شود."}]},{"word":"das Wunder","en":"miracle, wonder","ru":"чудо","vi":"điều kỳ diệu","fa":"معجزه","examples":[{"de":"Es grenzt an ein Wunder, dass er überlebt hat.","en":"It's almost a miracle that he survived.","ru":"То, что он выжил, почти чудо.","vi":"Thật là một phép lạ khi anh ấy sống sót.","fa":"این یک معجزه است که او زنده مانده است."},{"de":"Kein Wunder, dass du müde bist.","en":"No wonder you're tired.","ru":"Неудивительно, что ты устал.","vi":"Không có gì ngạc nhiên khi bạn mệt mỏi.","fa":"جای تعجب نیست که شما خسته هستید."}]},{"word":"wundern","en":"to surprise; (reflexive) to be surprised, to wonder","ru":"удивлять; (возвр.) удивляться","vi":"ngạc nhiên","fa":"تعجب","examples":[{"de":"Es wundert mich, dass du noch wach bist.","en":"It surprises me that you're still awake.","ru":"Меня удивляет, что ты ещё не спишь.","vi":"Tôi ngạc nhiên là bạn vẫn còn thức.","fa":"تعجب میکنم که هنوز بیداری"},{"de":"Ich wundere mich über sein Verhalten.","en":"I am surprised at his behaviour.","ru":"Я удивляюсь его поведению.","vi":"Tôi ngạc nhiên trước hành vi của anh ấy.","fa":"من از رفتار او تعجب می کنم."},{"de":"Das wundert mich gar nicht.","en":"That doesn't surprise me at all.","ru":"Меня это совсем не удивляет.","vi":"Điều đó không làm tôi ngạc nhiên chút nào.","fa":"این اصلاً من را شگفت زده نمی کند."}]},{"word":"wunderschön","en":"beautiful, gorgeous, lovely","ru":"прекрасный, красивый","vi":"đẹp","fa":"زیبا","examples":[{"de":"Der Sonnenuntergang am Meer war wunderschön.","en":"The sunset by the sea was beautiful.","ru":"Закат у моря был прекрасен.","vi":"Hoàng hôn bên biển thật đẹp.","fa":"غروب خورشید در کنار دریا بسیار زیبا بود."},{"de":"Sie trug ein wunderschönes Kleid.","en":"She wore a gorgeous dress.","ru":"Она была в прекрасном платье.","vi":"Cô ấy đang mặc một chiếc váy đẹp.","fa":"لباس زیبایی پوشیده بود."},{"de":"Wir hatten einen wunderschönen Tag im Park.","en":"We had a lovely day in the park.","ru":"У нас был чудесный день в парке.","vi":"Chúng tôi đã có một ngày tuyệt vời ở công viên.","fa":"یک روز فوق العاده در پارک داشتیم."}]},{"word":"die Wurst","en":"sausage","ru":"колбаса","vi":"xúc xích","fa":"سوسیس","examples":[{"de":"Zum Frühstück isst er gern Wurst und Brot.","en":"For breakfast he likes to eat sausage and bread.","ru":"На завтрак он любит есть колбасу с хлебом.","vi":"Anh ấy thích ăn xúc xích và bánh mì vào bữa sáng.","fa":"دوست دارد صبحانه سوسیس و نان بخورد."},{"de":"Auf dem Grill liegen mehrere Würste.","en":"There are several sausages on the grill.","ru":"На гриле лежит несколько колбасок.","vi":"Có một số xúc xích trên vỉ nướng.","fa":"چندین سوسیس روی کباب وجود دارد."}]},{"word":"würzen","en":"to season, to spice","ru":"приправлять, добавлять специи","vi":"mùa","fa":"فصل","examples":[{"de":"Würze die Suppe mit Salz und frischen Kräutern.","en":"Season the soup with salt and fresh herbs.","ru":"Приправь суп солью и свежими травами.","vi":"Nêm súp với muối và rau thơm tươi.","fa":"سوپ را با نمک و سبزیجات تازه مزه دار کنید."},{"de":"Er würzt das Fleisch, bevor er es brät.","en":"He seasons the meat before frying it.","ru":"Он приправляет мясо, прежде чем его жарить.","vi":"Anh ấy nêm gia vị vào thịt trước khi chiên.","fa":"گوشت را قبل از سرخ کردن مزه دار می کند."},{"de":"Man sollte das Gericht erst am Ende würzen.","en":"You should only season the dish at the end.","ru":"Блюдо следует приправлять только в конце.","vi":"Bạn chỉ nên nêm món ăn vào cuối.","fa":"فقط باید در آخر غذا را مزه دار کنید."}]},{"word":"würzig","en":"savoury","ru":"пряный, острый (насыщенный по вкусу)","vi":"vị cay","fa":"تند","examples":[{"de":"Der Käse ist sehr würzig und kräftig.","en":"The cheese is very savoury and strong.","ru":"Сыр очень пряный и насыщенный.","vi":"Phô mai rất cay và đậm đà.","fa":"پنیر بسیار تند و قوی است."},{"de":"Ich mag würzige Gerichte aus Indien.","en":"I like spicy, savoury dishes from India.","ru":"Мне нравятся пряные блюда из Индии.","vi":"Tôi thích các món ăn cay từ Ấn Độ.","fa":"من غذاهای تند هندی را دوست دارم."},{"de":"Die Soße ist angenehm würzig.","en":"The sauce is pleasantly savoury.","ru":"Соус приятно пряный.","vi":"Nước sốt có vị cay dễ chịu.","fa":"سس دلپذیری تند است."}]},{"word":"die Wüste","en":"desert","ru":"пустыня","vi":"sa mạc","fa":"صحرا","examples":[{"de":"In der Wüste fällt fast nie Regen.","en":"In the desert it almost never rains.","ru":"В пустыне почти никогда не идёт дождь.","vi":"Mưa hầu như không bao giờ rơi trên sa mạc.","fa":"باران تقریباً هرگز در بیابان نمی بارد."},{"de":"Durch die Erwärmung breiten sich die Wüsten immer weiter aus.","en":"Because of warming, the deserts are spreading further and further.","ru":"Из-за потепления пустыни всё больше расширяются.","vi":"Do sự nóng lên, các sa mạc ngày càng trở nên phổ biến.","fa":"به دلیل گرم شدن هوا، بیابان ها روز به روز گسترده تر می شوند."},{"de":"Tagsüber ist es in der Wüste sehr heiß und nachts kalt.","en":"During the day it is very hot in the desert and cold at night.","ru":"Днём в пустыне очень жарко, а ночью холодно.","vi":"Ở sa mạc rất nóng vào ban ngày và lạnh vào ban đêm.","fa":"روزها در کویر بسیار گرم و شبها سرد است."}]},{"word":"die Wut","en":"anger; rage","ru":"гнев; ярость","vi":"sự tức giận","fa":"خشم","examples":[{"de":"Vor Wut konnte er kaum sprechen.","en":"He could hardly speak out of anger.","ru":"От гнева он едва мог говорить.","vi":"Anh khó có thể nói được vì tức giận.","fa":"از عصبانیت به سختی می توانست حرف بزند."},{"de":"Ihre Wut verflog so schnell, wie sie gekommen war.","en":"Her anger faded as quickly as it had come.","ru":"Её гнев прошёл так же быстро, как и появился.","vi":"Cơn giận của cô biến mất nhanh chóng như khi nó xuất hiện.","fa":"عصبانیت او به سرعت از بین رفت."}]},{"word":"wütend","en":"furious, angry","ru":"разъярённый, злой","vi":"tức giận","fa":"عصبانی","examples":[{"de":"Er war wütend, weil der Zug Verspätung hatte.","en":"He was furious because the train was delayed.","ru":"Он был в ярости, потому что поезд опоздал.","vi":"Anh ấy tức giận vì tàu đến muộn.","fa":"او عصبانی بود زیرا قطار دیر کرده بود."},{"de":"Sie schaute mich wütend an.","en":"She looked at me angrily.","ru":"Она злобно посмотрела на меня.","vi":"Cô ấy nhìn tôi giận dữ.","fa":"با عصبانیت به من نگاه کرد."}]},{"word":"die Yogalehrerin","en":"yoga teacher (female)","ru":"преподавательница йоги, инструктор по йоге (женщина)","vi":"giáo viên yoga","fa":"معلم یوگا","examples":[{"de":"Die Yogalehrerin korrigierte vorsichtig meine Haltung.","en":"The yoga teacher gently corrected my posture.","ru":"Преподавательница йоги мягко поправила мою осанку.","vi":"Giáo viên yoga cẩn thận chỉnh lại tư thế cho tôi.","fa":"معلم یوگا با دقت وضعیت من را اصلاح کرد."},{"de":"Unsere Yogalehrerin spricht sehr ruhig.","en":"Our yoga teacher speaks very calmly.","ru":"Наша преподавательница йоги говорит очень спокойно.","vi":"Giáo viên yoga của chúng tôi nói chuyện rất bình tĩnh.","fa":"معلم یوگا ما خیلی آرام صحبت می کند."},{"de":"Die Yogalehrerin zeigte jede Bewegung langsam vor.","en":"The yoga teacher demonstrated each movement slowly.","ru":"Преподавательница йоги медленно показывала каждое движение.","vi":"Giáo viên yoga thực hiện từng động tác một cách chậm rãi.","fa":"معلم یوگا هر حرکت را به آرامی نشان داد."}]},{"word":"die Zahl","en":"number","ru":"число, цифра","vi":"số","fa":"شماره","examples":[{"de":"Die Zahl der Studenten steigt jedes Jahr.","en":"The number of students increases every year.","ru":"Число студентов растёт каждый год.","vi":"Số lượng sinh viên tăng lên hàng năm.","fa":"هر سال بر تعداد دانش آموزان افزوده می شود."},{"de":"Kannst du diese Zahl laut vorlesen?","en":"Can you read this number out loud?","ru":"Можешь прочитать это число вслух?","vi":"Bạn có thể đọc to con số này không?","fa":"آیا می توانید این عدد را با صدای بلند بخوانید؟"}]},{"word":"zahlen","en":"to pay","ru":"платить","vi":"trả tiền","fa":"پرداخت کنید","examples":[{"de":"Ich möchte bitte zahlen.","en":"I would like to pay, please.","ru":"Я хотел бы оплатить, пожалуйста.","vi":"Tôi muốn trả tiền xin vui lòng.","fa":"من می خواهم پرداخت کنم لطفا"},{"de":"Er zahlt die Miete immer pünktlich.","en":"He always pays the rent on time.","ru":"Он всегда платит арендную плату вовремя.","vi":"Anh ấy luôn trả tiền thuê nhà đúng hạn.","fa":"او همیشه کرایه خانه را به موقع پرداخت می کند."}]},{"word":"zählen","en":"to count","ru":"считать","vi":"đếm","fa":"شمارش","examples":[{"de":"Das Kind kann schon bis hundert zählen.","en":"The child can already count to a hundred.","ru":"Ребёнок уже умеет считать до ста.","vi":"Đứa trẻ đã có thể đếm đến một trăm.","fa":"کودک می تواند تا صد بشمارد."},{"de":"Ich zähle auf deine Hilfe.","en":"I'm counting on your help.","ru":"Я рассчитываю на твою помощь.","vi":"Tôi đang trông cậy vào sự giúp đỡ của bạn.","fa":"من روی کمک شما حساب می کنم."}]},{"word":"der Zähler","en":"numerator","ru":"числитель","vi":"quầy","fa":"شمارنده","examples":[{"de":"Der Zähler steht über dem Bruchstrich.","en":"The numerator is above the fraction line.","ru":"Числитель стоит над дробной чертой.","vi":"Tử số nằm phía trên dòng phân số.","fa":"شمارنده بالای خط کسری است."},{"de":"Im Bruch zwei Drittel ist zwei der Zähler.","en":"In the fraction two thirds, two is the numerator.","ru":"В дроби две трети два — это числитель.","vi":"Trong phân số hai phần ba, hai là tử số.","fa":"در کسر دو ثلث، شماره دو است."},{"de":"Wenn der Zähler null ist, ist der ganze Bruch null.","en":"When the numerator is zero, the whole fraction is zero.","ru":"Когда числитель равен нулю, вся дробь равна нулю.","vi":"Nếu tử số bằng 0 thì toàn bộ phân số bằng 0.","fa":"اگر عدد صفر باشد کل کسر صفر می شود."}]},{"word":"zahlreich","en":"numerous, many","ru":"многочисленный","vi":"nhiều","fa":"متعدد","examples":[{"de":"Zahlreiche Gäste kamen zur Eröffnung.","en":"Numerous guests came to the opening.","ru":"На открытие пришли многочисленные гости.","vi":"Đông đảo khách mời đến dự khai trương.","fa":"مهمانان زیادی به افتتاحیه آمدند."},{"de":"Es gibt zahlreiche Gründe für diese Entscheidung.","en":"There are numerous reasons for this decision.","ru":"Есть многочисленные причины для этого решения.","vi":"Có rất nhiều lý do cho quyết định này.","fa":"دلایل متعددی برای این تصمیم وجود دارد."},{"de":"Sie hat zahlreiche Bücher geschrieben.","en":"She has written numerous books.","ru":"Она написала многочисленные книги.","vi":"Cô đã viết rất nhiều cuốn sách.","fa":"او کتاب های متعددی نوشته است."}]},{"word":"die Zahlung","en":"payment","ru":"платёж, оплата","vi":"việc thanh toán","fa":"پرداخت","examples":[{"de":"Die Zahlung erfolgt innerhalb von zwei Wochen.","en":"Payment is made within two weeks.","ru":"Оплата производится в течение двух недель.","vi":"Thanh toán sẽ được thực hiện trong vòng hai tuần.","fa":"پرداخت ظرف دو هفته انجام خواهد شد."},{"de":"Wir haben Ihre Zahlung noch nicht erhalten.","en":"We have not yet received your payment.","ru":"Мы ещё не получили вашего платежа.","vi":"Chúng tôi chưa nhận được thanh toán của bạn.","fa":"ما هنوز مبلغ شما را دریافت نکرده ایم."},{"de":"Welche Art der Zahlung bevorzugen Sie?","en":"Which method of payment do you prefer?","ru":"Какой способ оплаты вы предпочитаете?","vi":"Bạn thích loại thanh toán nào hơn?","fa":"کدام نوع پرداخت را ترجیح می دهید؟"}]},{"word":"die Zahlungsoption","en":"payment option","ru":"способ оплаты","vi":"tùy chọn thanh toán","fa":"گزینه پرداخت","examples":[{"de":"Welche Zahlungsoption möchten Sie wählen?","en":"Which payment option would you like to choose?","ru":"Какой способ оплаты вы хотите выбрать?","vi":"Bạn muốn chọn tùy chọn thanh toán nào?","fa":"کدام گزینه پرداخت را می خواهید انتخاب کنید؟"},{"de":"Der Shop bietet mehrere Zahlungsoptionen an.","en":"The shop offers several payment options.","ru":"Магазин предлагает несколько способов оплаты.","vi":"Cửa hàng cung cấp nhiều lựa chọn thanh toán.","fa":"این فروشگاه چندین گزینه پرداخت را ارائه می دهد."},{"de":"Die Zahlungsoption „Rechnung“ ist sehr beliebt.","en":"The payment option \"invoice\" is very popular.","ru":"Способ оплаты «по счёту» очень популярен.","vi":"Tùy chọn thanh toán “hóa đơn” rất phổ biến.","fa":"گزینه پرداخت \"فاکتور\" بسیار محبوب است."}]},{"word":"der Zahn","en":"tooth","ru":"зуб","vi":"cái răng","fa":"دندان","examples":[{"de":"Ich muss zum Zahnarzt, mein Zahn tut weh.","en":"I have to go to the dentist, my tooth hurts.","ru":"Мне нужно к стоматологу, у меня болит зуб.","vi":"Tôi phải đến nha sĩ, răng tôi đau quá.","fa":"من باید برم دندانپزشک، دندانم درد می کند."},{"de":"Putz dir jeden Abend die Zähne.","en":"Brush your teeth every evening.","ru":"Чисти зубы каждый вечер.","vi":"Đánh răng vào mỗi buổi tối.","fa":"هر شب دندان های خود را مسواک بزنید."}]},{"word":"die Zahncreme","en":"toothpaste","ru":"зубная паста","vi":"kem đánh răng","fa":"خمیر دندان","examples":[{"de":"Die Zahncreme ist fast leer.","en":"The toothpaste is almost empty.","ru":"Зубная паста почти закончилась.","vi":"Kem đánh răng gần như đã hết.","fa":"خمیر دندان تقریبا خالی است."},{"de":"Ich kaufe immer Zahncreme mit Fluorid.","en":"I always buy toothpaste with fluoride.","ru":"Я всегда покупаю зубную пасту с фтором.","vi":"Tôi luôn mua kem đánh răng có fluoride.","fa":"من همیشه خمیر دندان با فلوراید می خرم."},{"de":"Tu nicht so viel Zahncreme auf die Bürste.","en":"Don't put so much toothpaste on the brush.","ru":"Не выдавливай столько зубной пасты на щётку.","vi":"Đừng đổ quá nhiều kem đánh răng lên bàn chải.","fa":"خمیر دندان زیاد روی مسواک نریزید."}]},{"word":"die Zahncrème","en":"toothpaste (variant spelling)","ru":"зубная паста (вариант написания)","vi":"kem đánh răng","fa":"خمیر دندان","examples":[{"de":"Auf der Tube stand „Zahncrème“ mit Akzent.","en":"The tube said \"Zahncrème\" with an accent.","ru":"На тюбике было написано «Zahncrème» с акцентом.","vi":"Ống nói “kem đánh răng” có giọng.","fa":"لوله با لهجه گفت: \"کرم دندان\"."},{"de":"Manche Marken schreiben Zahncrème mit Accent grave.","en":"Some brands write Zahncrème with a grave accent.","ru":"Некоторые марки пишут Zahncrème с грависом.","vi":"Một số hãng viết kem đánh răng có chữ Accent.","fa":"برخی از مارک ها خمیر دندان را با قبر اکسنت می نویسند."},{"de":"Die Zahncrème für Kinder ist besonders mild.","en":"The toothpaste for children is particularly mild.","ru":"Зубная паста для детей особенно мягкая.","vi":"Kem đánh răng dành cho trẻ em đặc biệt dịu nhẹ.","fa":"خمیر دندان برای کودکان به خصوص ملایم است."}]},{"word":"die Zähne zusammenbeißen","en":"to grit one's teeth (endure)","ru":"стиснуть зубы (перетерпеть)","vi":"nghiến răng","fa":"دندان قروچه کردن","examples":[{"de":"Die letzten Kilometer musste ich die Zähne zusammenbeißen.","en":"For the last few kilometres I had to grit my teeth.","ru":"Последние километры мне пришлось стиснуть зубы.","vi":"Tôi đã phải nghiến răng trong vài km cuối cùng.","fa":"چند کیلومتر آخر مجبور شدم دندونم رو به هم فشار بدم."}]},{"word":"die Zange","en":"pliers, tongs","ru":"клещи, щипцы","vi":"cái kìm","fa":"انبردست","examples":[{"de":"Er zieht den Nagel mit einer Zange heraus.","en":"He pulls out the nail with pliers.","ru":"Он вытаскивает гвоздь клещами.","vi":"Anh ta rút chiếc đinh ra bằng kìm.","fa":"میخ را با انبردست بیرون می آورد."},{"de":"Ich brauche eine Zange, um den Draht zu schneiden.","en":"I need pliers to cut the wire.","ru":"Мне нужны клещи, чтобы перерезать проволоку.","vi":"Tôi cần cái kìm để cắt dây.","fa":"برای بریدن سیم به انبردست نیاز دارم."}]},{"word":"zapfen","en":"to pour, to draw (a beer from the tap)","ru":"наливать, разливать (пиво из-под крана)","vi":"gõ nhẹ","fa":"ضربه بزنید","examples":[{"de":"Der Wirt zapft ein frisches Bier vom Fass.","en":"The landlord draws a fresh beer from the barrel.","ru":"Хозяин наливает свежее пиво из бочки.","vi":"Người chủ quán rót một cốc bia tươi.","fa":"مسافرخانه‌دار آبجوی تازه‌ای می‌خورد."},{"de":"Ein gutes Bier zu zapfen braucht etwas Übung.","en":"Pouring a good beer takes a bit of practice.","ru":"Чтобы хорошо налить пиво, нужна некоторая сноровка.","vi":"Để có được một cốc bia ngon cần phải thực hành một chút.","fa":"کشیدن یک آبجو خوب نیاز به تمرین دارد."},{"de":"Sie zapfte zwei Gläser und stellte sie auf den Tresen.","en":"She drew two glasses and put them on the counter.","ru":"Она налила два бокала и поставила их на стойку.","vi":"Cô rót hai ly và đặt chúng lên quầy.","fa":"دو لیوان ریخت و روی پیشخوان گذاشت."}]},{"word":"das Zeichen","en":"sign, signal","ru":"знак, сигнал","vi":"dấu hiệu","fa":"علامت","examples":[{"de":"Der Polizist gibt den Autos ein Zeichen zum Anhalten.","en":"The police officer gives the cars a signal to stop.","ru":"Полицейский даёт машинам сигнал остановиться.","vi":"Viên cảnh sát ra hiệu cho các xe dừng lại.","fa":"افسر پلیس به ماشین ها علامت می دهد که بایستند."},{"de":"Ein Lächeln ist oft ein Zeichen der Freundlichkeit.","en":"A smile is often a sign of friendliness.","ru":"Улыбка часто является знаком дружелюбия.","vi":"Một nụ cười thường là dấu hiệu của sự thân thiện.","fa":"لبخند اغلب نشانه دوستی است."}]},{"word":"der Zeichentrick","en":"cartoon animation; animated cartoon","ru":"мультфильм, рисованная анимация","vi":"phim hoạt hình","fa":"کارتون","examples":[{"de":"Die Kinder schauen am Samstag gern Zeichentrick.","en":"The children like watching cartoons on Saturdays.","ru":"Дети любят по субботам смотреть мультфильмы.","vi":"Bọn trẻ thích xem phim hoạt hình vào thứ bảy.","fa":"بچه ها دوست دارند شنبه کارتون ببینند."},{"de":"Dieser Zeichentrick ist auch für Erwachsene lustig.","en":"This cartoon is funny for adults too.","ru":"Этот мультфильм смешной и для взрослых.","vi":"Phim hoạt hình này cũng hài hước đối với người lớn.","fa":"این کارتون برای بزرگسالان نیز خنده دار است."},{"de":"Früher wurde jeder Zeichentrick von Hand gemalt.","en":"In the past every cartoon was drawn by hand.","ru":"Раньше каждый мультфильм рисовали вручную.","vi":"Trước đây, mọi phim hoạt hình đều được vẽ bằng tay.","fa":"در گذشته هر کارتون با دست نقاشی می شد."}]},{"word":"zeichnen","en":"to draw","ru":"рисовать","vi":"vẽ","fa":"نقاشی کشیدن","examples":[{"de":"Meine Tochter zeichnet gern Tiere.","en":"My daughter likes to draw animals.","ru":"Моя дочь любит рисовать животных.","vi":"Con gái tôi thích vẽ động vật.","fa":"دخترم دوست دارد حیوانات نقاشی کند."},{"de":"Er zeichnet einen Plan für das neue Haus.","en":"He's drawing a plan for the new house.","ru":"Он рисует план нового дома.","vi":"Anh ấy vẽ một kế hoạch cho ngôi nhà mới.","fa":"او برای خانه جدید نقشه می کشد."}]},{"word":"die Zeichnung","en":"drawing; sketch","ru":"рисунок; чертёж","vi":"bản vẽ","fa":"نقاشی","examples":[{"de":"Die Zeichnung des Kindes hängt an der Wand.","en":"The child's drawing is hanging on the wall.","ru":"Детский рисунок висит на стене.","vi":"Bức vẽ của đứa trẻ treo trên tường.","fa":"نقاشی کودک روی دیوار آویزان است."},{"de":"Er machte eine genaue Zeichnung des Hauses.","en":"He made a precise drawing of the house.","ru":"Он сделал точный чертёж дома.","vi":"Anh ấy đã vẽ một bản vẽ chi tiết của ngôi nhà.","fa":"او یک نقاشی دقیق از خانه انجام داد."},{"de":"Diese Zeichnung zeigt den Aufbau der Maschine.","en":"This drawing shows the structure of the machine.","ru":"Этот чертёж показывает устройство машины.","vi":"Bản vẽ này cho thấy cấu trúc của máy.","fa":"این نقشه ساختار دستگاه را نشان می دهد."}]},{"word":"zeigen","en":"to show","ru":"показывать","vi":"hiển thị","fa":"نشان می دهد","examples":[{"de":"Kannst du mir bitte den Weg zeigen?","en":"Can you please show me the way?","ru":"Ты можешь, пожалуйста, показать мне дорогу?","vi":"Bạn có thể vui lòng chỉ đường cho tôi được không?","fa":"میشه لطفا راه رو به من نشون بدی؟"},{"de":"Er zeigt seinen Freunden die neuen Fotos.","en":"He shows his friends the new photos.","ru":"Он показывает друзьям новые фотографии.","vi":"Anh ấy cho bạn bè xem những bức ảnh mới.","fa":"او عکس های جدید را به دوستانش نشان می دهد."}]},{"word":"die Zeile","en":"line (of text)","ru":"строка (текста)","vi":"dòng","fa":"خط","examples":[{"de":"Lies bitte die erste Zeile noch einmal.","en":"Please read the first line again.","ru":"Пожалуйста, прочитай ещё раз первую строку.","vi":"Xin vui lòng đọc lại dòng đầu tiên.","fa":"لطفا سطر اول را دوباره بخوانید."},{"de":"In diesem Brief fehlt eine Zeile.","en":"A line is missing in this letter.","ru":"В этом письме не хватает строки.","vi":"Có một dòng bị thiếu trong bức thư này.","fa":"در این نامه خطی وجود ندارد."}]},{"word":"die Zeit","en":"time","ru":"время","vi":"thời gian","fa":"زمان","examples":[{"de":"Ich habe heute leider keine Zeit.","en":"I unfortunately have no time today.","ru":"У меня, к сожалению, сегодня нет времени.","vi":"Thật không may là hôm nay tôi không có thời gian.","fa":"متاسفانه امروز وقت ندارم"},{"de":"Die Zeit vergeht sehr schnell.","en":"Time passes very quickly.","ru":"Время проходит очень быстро.","vi":"Thời gian trôi qua rất nhanh.","fa":"زمان خیلی سریع می گذرد."}]},{"word":"der Zeitabschnitt","en":"period of time, era","ru":"период, отрезок времени, эпоха","vi":"khoảng thời gian","fa":"دوره زمانی","examples":[{"de":"Dieser Zeitabschnitt war geprägt von Kriegen.","en":"This period was shaped by wars.","ru":"Этот период был отмечен войнами.","vi":"Thời kỳ này được đánh dấu bằng chiến tranh.","fa":"این دوره با جنگ ها مشخص شد."},{"de":"Wir behandeln einen wichtigen Zeitabschnitt der Geschichte.","en":"We are dealing with an important period of history.","ru":"Мы изучаем важный период истории.","vi":"Chúng tôi đề cập đến một giai đoạn lịch sử quan trọng.","fa":"ما یک دوره مهم از تاریخ را پوشش می دهیم."},{"de":"In jenem Zeitabschnitt lebten viele berühmte Künstler.","en":"In that period many famous artists lived.","ru":"В тот период жили многие знаменитые художники.","vi":"Nhiều nghệ sĩ nổi tiếng đã sống trong thời kỳ đó.","fa":"بسیاری از هنرمندان مشهور در آن دوره زندگی می کردند."}]},{"word":"das Zeitalter","en":"era, age","ru":"эпоха, эра, век","vi":"tuổi","fa":"سن","examples":[{"de":"Wir leben im digitalen Zeitalter.","en":"We live in the digital age.","ru":"Мы живём в цифровую эпоху.","vi":"Chúng ta đang sống trong thời đại kỹ thuật số.","fa":"ما در عصر دیجیتال زندگی می کنیم."},{"de":"Das industrielle Zeitalter veränderte die Arbeit grundlegend.","en":"The industrial age changed work fundamentally.","ru":"Индустриальная эпоха коренным образом изменила труд.","vi":"Thời đại công nghiệp đã thay đổi căn bản công việc.","fa":"عصر صنعتی اساساً کار را تغییر داد."},{"de":"Mit dieser Erfindung begann ein neues Zeitalter.","en":"With this invention a new era began.","ru":"С этим изобретением началась новая эра.","vi":"Với phát minh này, một kỷ nguyên mới đã bắt đầu.","fa":"با این اختراع عصر جدیدی آغاز شد."}]},{"word":"der Zeitpunkt","en":"point in time; moment","ru":"момент времени, момент","vi":"thời gian","fa":"زمان بندی","examples":[{"de":"Zu diesem Zeitpunkt war ich noch nicht geboren.","en":"At that point in time I had not yet been born.","ru":"В тот момент я ещё не родился.","vi":"Lúc đó tôi chưa được sinh ra.","fa":"من هنوز در آن مقطع به دنیا نیامده بودم."},{"de":"Wir müssen den richtigen Zeitpunkt abwarten.","en":"We have to wait for the right moment.","ru":"Нам нужно дождаться подходящего момента.","vi":"Chúng ta phải chờ thời điểm thích hợp.","fa":"باید منتظر زمان مناسب باشیم."},{"de":"Zum jetzigen Zeitpunkt kann ich nichts versprechen.","en":"At the present time I can't promise anything.","ru":"В настоящий момент я ничего не могу обещать.","vi":"Tại thời điểm này tôi không thể hứa hẹn bất cứ điều gì.","fa":"در این مرحله نمی توانم قولی بدهم."}]},{"word":"die Zeitschrift","en":"magazine","ru":"журнал","vi":"tạp chí","fa":"مجله","examples":[{"de":"Meine Mutter liest gern eine Zeitschrift über Mode.","en":"My mother likes reading a fashion magazine.","ru":"Моя мама любит читать журнал о моде.","vi":"Mẹ tôi thích đọc tạp chí về thời trang.","fa":"مادرم دوست دارد یک مجله درباره مد بخواند."},{"de":"Diese Zeitschrift erscheint einmal im Monat.","en":"This magazine is published once a month.","ru":"Этот журнал выходит раз в месяц.","vi":"Tạp chí này được xuất bản mỗi tháng một lần.","fa":"این مجله ماهی یک بار منتشر می شود."}]},{"word":"die Zeitung","en":"newspaper","ru":"газета","vi":"tờ báo","fa":"روزنامه","examples":[{"de":"Mein Vater liest jeden Morgen die Zeitung.","en":"My father reads the newspaper every morning.","ru":"Мой отец каждое утро читает газету.","vi":"Bố tôi đọc báo mỗi sáng.","fa":"پدرم هر روز صبح روزنامه می خواند."},{"de":"In der Zeitung stand ein interessanter Artikel.","en":"There was an interesting article in the newspaper.","ru":"В газете была интересная статья.","vi":"Có một bài viết thú vị trên báo.","fa":"مطلب جالبی در روزنامه بود."}]},{"word":"das Zelt","en":"tent","ru":"палатка","vi":"cái lều","fa":"چادر","examples":[{"de":"Wir haben unser Zelt am See aufgebaut.","en":"We set up our tent by the lake.","ru":"Мы поставили нашу палатку у озера.","vi":"Chúng tôi dựng lều bên hồ.","fa":"چادرمان را کنار دریاچه برپا کردیم."},{"de":"Das Zelt ist für vier Personen groß genug.","en":"The tent is big enough for four people.","ru":"Палатка достаточно велика для четырёх человек.","vi":"Lều đủ lớn cho bốn người.","fa":"چادر برای چهار نفر بزرگ است."}]},{"word":"zelten","en":"to camp","ru":"разбивать лагерь, ночевать в палатке","vi":"cắm trại","fa":"کمپینگ","examples":[{"de":"Im Sommer zelten wir oft in den Bergen.","en":"In summer we often go camping in the mountains.","ru":"Летом мы часто ночуем в палатке в горах.","vi":"Vào mùa hè chúng tôi thường cắm trại trên núi.","fa":"در تابستان اغلب در کوهستان چادر می زنیم."},{"de":"Hier darf man nicht zelten.","en":"Camping is not allowed here.","ru":"Здесь нельзя разбивать палатку.","vi":"Bạn không được phép cắm trại ở đây.","fa":"شما اجازه ندارید اینجا کمپ بزنید."}]},{"word":"der Zentner","en":"a hundredweight (a unit of mass, 50 kilograms in Germany)","ru":"центнер (единица массы, в Германии 50 килограммов)","vi":"một trăm cân","fa":"the hundredweight","examples":[{"de":"Zehn zahme Ziegen zogen zehn Zentner Zucker zum Zoo.","en":"Ten tame goats hauled ten hundredweights of sugar to the zoo.","ru":"Десять ручных коз притащили в зоопарк десять центнеров сахара.","vi":"Mười con dê thuần hóa mang mười trăm cân đường đến sở thú.","fa":"ده بز رام ده صد وزن شکر به باغ وحش آوردند."},{"de":"Ein Sack Kartoffeln wiegt hier ungefähr einen Zentner.","en":"A sack of potatoes here weighs roughly a hundredweight.","ru":"Мешок картошки здесь весит примерно центнер.","vi":"Một bao khoai tây ở đây nặng khoảng một trăm cân.","fa":"یک گونی سیب زمینی در اینجا حدود صد وزن دارد."},{"de":"Der Bauer lud mehrere Zentner Getreide auf den Anhänger.","en":"The farmer loaded several hundredweights of grain onto the trailer.","ru":"Фермер погрузил на прицеп несколько центнеров зерна.","vi":"Người nông dân chất hàng trăm tạ ngũ cốc lên xe kéo.","fa":"کشاورز چند صد وزن دانه را در تریلر بار کرد."}]},{"word":"zentral","en":"central","ru":"центральный","vi":"trung ương","fa":"مرکزی","examples":[{"de":"Die Wohnung liegt sehr zentral.","en":"The apartment is located very centrally.","ru":"Квартира расположена очень центрально.","vi":"Căn hộ nằm rất trung tâm.","fa":"آپارتمان بسیار مرکزی است."},{"de":"Der Bahnhof ist ein zentraler Treffpunkt in der Stadt.","en":"The train station is a central meeting point in the city.","ru":"Вокзал — центральное место встречи в городе.","vi":"Nhà ga xe lửa là điểm tập trung của thành phố.","fa":"ایستگاه قطار یک نقطه ملاقات مرکزی در شهر است."}]},{"word":"das Zentrum","en":"center","ru":"центр","vi":"trung tâm","fa":"مرکز","examples":[{"de":"Wir treffen uns im Zentrum der Stadt.","en":"We are meeting in the city center.","ru":"Мы встречаемся в центре города.","vi":"Chúng tôi gặp nhau ở trung tâm thành phố.","fa":"در مرکز شهر همدیگر را می بینیم."},{"de":"Das Einkaufszentrum liegt nicht weit vom Zentrum.","en":"The shopping center is not far from the center.","ru":"Торговый центр находится недалеко от центра.","vi":"Trung tâm mua sắm cách trung tâm không xa.","fa":"مرکز خرید فاصله چندانی با مرکز ندارد."}]},{"word":"zerstören","en":"to destroy","ru":"разрушать","vi":"phá hủy","fa":"نابود کردن","examples":[{"de":"Der Sturm hat viele Häuser zerstört.","en":"The storm destroyed many houses.","ru":"Буря разрушила много домов.","vi":"Cơn bão đã phá hủy nhiều ngôi nhà.","fa":"طوفان خانه های زیادی را ویران کرد."},{"de":"Bitte zerstöre nicht meine Arbeit!","en":"Please don't destroy my work!","ru":"Пожалуйста, не разрушай мою работу!","vi":"Làm ơn đừng phá hủy tác phẩm của tôi!","fa":"لطفا کار من را خراب نکنید!"}]},{"word":"das Zerti","en":"cert (colloquial short for certificate)","ru":"сертификат (разговорное сокращение)","vi":"giấy chứng nhận","fa":"گواهی","examples":[{"de":"Hast du dein Zerti vom Kurs schon bekommen?","en":"Have you already got your cert from the course?","ru":"Ты уже получил свой сертификат с курса?","vi":"Bạn đã nhận được chứng chỉ từ khóa học chưa?","fa":"آیا قبلا گواهینامه خود را از دوره دریافت کرده اید؟"},{"de":"Ohne das Zerti darf ich nicht weiterarbeiten.","en":"Without the cert I'm not allowed to keep working.","ru":"Без сертификата мне нельзя продолжать работать.","vi":"Nếu không có chứng chỉ tôi không được phép tiếp tục làm việc.","fa":"بدون گواهینامه اجازه ادامه کار را ندارم."},{"de":"Sie zeigte stolz ihr Zerti vom Sprachkurs.","en":"She proudly showed her cert from the language course.","ru":"Она с гордостью показала сертификат с языкового курса.","vi":"Cô tự hào khoe chứng chỉ của khóa học ngoại ngữ.","fa":"او با افتخار مدرک خود را از دوره زبان نشان داد."}]},{"word":"das Zertifikat","en":"certificate","ru":"сертификат","vi":"giấy chứng nhận","fa":"گواهی","examples":[{"de":"Nach dem Kurs bekommen Sie ein Zertifikat.","en":"After the course you will receive a certificate.","ru":"После курса вы получите сертификат.","vi":"Sau khóa học bạn sẽ nhận được chứng chỉ.","fa":"پس از پایان دوره گواهینامه دریافت خواهید کرد."},{"de":"Ich brauche das Zertifikat für meine Bewerbung.","en":"I need the certificate for my application.","ru":"Мне нужен сертификат для моего заявления.","vi":"Tôi cần giấy chứng nhận cho đơn đăng ký của mình.","fa":"برای درخواستم به گواهی نیاز دارم"}]},{"word":"der Zettel","en":"note (piece of paper)","ru":"записка, листок","vi":"ghi chú","fa":"یادداشت","examples":[{"de":"Sie hat mir einen Zettel auf den Tisch gelegt.","en":"She left me a note on the table.","ru":"Она оставила мне записку на столе.","vi":"Cô ấy đặt một mảnh giấy lên bàn cho tôi.","fa":"او یک تکه کاغذ برای من روی میز گذاشت."},{"de":"Ich schreibe die Adresse auf einen Zettel.","en":"I'll write the address on a piece of paper.","ru":"Я запишу адрес на листке бумаги.","vi":"Tôi viết địa chỉ lên một tờ giấy.","fa":"آدرس را روی یک کاغذ می نویسم."}]},{"word":"das Zeug","en":"stuff, things","ru":"вещи, барахло; (перен.) чепуха","vi":"những thứ","fa":"چیزها","examples":[{"de":"Räum bitte dein Zeug vom Tisch weg.","en":"Please clear your stuff off the table.","ru":"Пожалуйста, убери свои вещи со стола.","vi":"Hãy dọn đồ đạc của bạn ra khỏi bàn.","fa":"لطفا مطالب خود را از روی جدول پاک کنید."},{"de":"Im Keller liegt noch jede Menge altes Zeug.","en":"There's still loads of old stuff in the cellar.","ru":"В подвале ещё полно старого барахла.","vi":"Vẫn còn rất nhiều đồ cũ ở tầng hầm.","fa":"هنوز خیلی چیزهای قدیمی در زیرزمین وجود دارد."},{"de":"Was ist denn das für komisches Zeug in der Tasche?","en":"What's that weird stuff in the bag?","ru":"Что за странная штука в сумке?","vi":"Thứ kì lạ trong túi của bạn là gì vậy?","fa":"آن چیزهای عجیب و غریب در کیف شما چیست؟"}]},{"word":"das Zeug/-zeug","en":"stuff, things","ru":"вещи, барахло","vi":"thứ/thứ đó","fa":"چیز/مواد","examples":[{"de":"Räum dein Zeug endlich auf!","en":"Finally tidy up your stuff!","ru":"Наконец-то убери свои вещи!","vi":"Cuối cùng hãy dọn dẹp đồ đạc của bạn!","fa":"بالاخره وسایلت را تمیز کن!"},{"de":"Wir brauchen Werkzeug, um das Regal zu reparieren.","en":"We need tools to repair the shelf.","ru":"Нам нужны инструменты, чтобы починить полку.","vi":"Chúng tôi cần các công cụ để sửa chữa kệ.","fa":"برای تعمیر قفسه به ابزار نیاز داریم."}]},{"word":"der Zeuge","en":"witness","ru":"свидетель","vi":"nhân chứng","fa":"شاهد","examples":[{"de":"Der Zeuge hat den Unfall genau beobachtet.","en":"The witness observed the accident closely.","ru":"Свидетель точно наблюдал за аварией.","vi":"Nhân chứng đã quan sát kỹ vụ tai nạn.","fa":"شاهد حادثه را از نزدیک مشاهده کرد."},{"de":"Die Polizei sucht Zeugen des Diebstahls.","en":"The police are looking for witnesses to the theft.","ru":"Полиция ищет свидетелей кражи.","vi":"Cảnh sát đang tìm kiếm nhân chứng của vụ trộm.","fa":"پلیس به دنبال شاهدان این سرقت است."}]},{"word":"die Zeugin","en":"witness (female)","ru":"свидетельница (женщина)","vi":"nhân chứng","fa":"شاهد","examples":[{"de":"Die Zeugin beschrieb den Täter genau.","en":"The witness described the offender precisely.","ru":"Свидетельница точно описала преступника.","vi":"Nhân chứng đã mô tả chi tiết về thủ phạm.","fa":"شاهد به تفصیل عامل جنایت را توصیف کرد."},{"de":"Eine Zeugin meldete sich nach dem Aufruf.","en":"A witness came forward after the appeal.","ru":"После обращения объявилась свидетельница.","vi":"Một nhân chứng đã đến sau cuộc gọi.","fa":"بعد از تماس شاهد آمد."},{"de":"Die Zeugin wurde vom Richter befragt.","en":"The witness was questioned by the judge.","ru":"Свидетельницу допросил судья.","vi":"Nhân chứng bị thẩm phán thẩm vấn.","fa":"شاهد مورد بازجویی قاضی قرار گرفت."}]},{"word":"das Zeugnis","en":"report card; certificate","ru":"свидетельство, табель (об успеваемости)","vi":"học bạ; chứng chỉ","fa":"کارنامه؛ گواهی","examples":[{"de":"Mein Sohn hat ein gutes Zeugnis bekommen.","en":"My son got a good report card.","ru":"Мой сын получил хороший табель.","vi":"Con trai tôi đã nhận được một phiếu báo điểm tốt.","fa":"پسرم کارنامه خوبی گرفت."},{"de":"Für die Bewerbung brauche ich mein Abschlusszeugnis.","en":"For the application I need my final certificate.","ru":"Для заявления мне нужен мой выпускной аттестат.","vi":"Tôi cần bằng tốt nghiệp của tôi để nộp đơn.","fa":"برای درخواست به مدرک دیپلمم نیاز دارم."}]},{"word":"ziehen","en":"to pull; to move (relocate)","ru":"тянуть; переезжать","vi":"kéo","fa":"کشیدن","examples":[{"de":"Bitte zieh die Tür zu, es zieht.","en":"Please pull the door shut, there's a draft.","ru":"Пожалуйста, закрой дверь, сквозит.","vi":"Hãy đóng cửa lại, có gió lùa.","fa":"لطفا در را ببندید، پیش نویس وجود دارد."},{"de":"Nächsten Monat ziehen wir nach Berlin.","en":"Next month we are moving to Berlin.","ru":"В следующем месяце мы переезжаем в Берлин.","vi":"Tháng tới chúng tôi sẽ chuyển đến Berlin.","fa":"ماه آینده به برلین نقل مکان می کنیم."}]},{"word":"das Ziel","en":"goal; destination","ru":"цель; пункт назначения","vi":"mục tiêu","fa":"هدف","examples":[{"de":"Mein Ziel ist es, die Prüfung zu bestehen.","en":"My goal is to pass the exam.","ru":"Моя цель — сдать экзамен.","vi":"Mục tiêu của tôi là vượt qua kỳ thi.","fa":"هدف من قبولی در امتحان است."},{"de":"Wir haben unser Ziel endlich erreicht.","en":"We finally reached our destination.","ru":"Мы наконец достигли нашей цели.","vi":"Cuối cùng chúng tôi đã đạt được mục tiêu của mình.","fa":"بالاخره به هدفمون رسیدیم."}]},{"word":"ziemlich","en":"quite, rather","ru":"довольно, весьма","vi":"khá","fa":"کاملا","examples":[{"de":"Das Wetter ist heute ziemlich kalt.","en":"The weather is quite cold today.","ru":"Погода сегодня довольно холодная.","vi":"Thời tiết hôm nay khá lạnh.","fa":"امروز هوا خیلی سرده"},{"de":"Die Prüfung war ziemlich schwer.","en":"The exam was rather difficult.","ru":"Экзамен был довольно трудным.","vi":"Bài kiểm tra khá khó khăn.","fa":"آزمون بسیار سخت بود."}]},{"word":"die Zigarette","en":"cigarette","ru":"сигарета","vi":"điếu thuốc","fa":"سیگار","examples":[{"de":"Er raucht zu viele Zigaretten am Tag.","en":"He smokes too many cigarettes a day.","ru":"Он курит слишком много сигарет в день.","vi":"Anh ấy hút quá nhiều thuốc lá mỗi ngày.","fa":"او در روز بیش از حد سیگار می کشد."},{"de":"Kannst du mir eine Zigarette geben?","en":"Can you give me a cigarette?","ru":"Ты можешь дать мне сигарету?","vi":"Bạn có thể cho tôi một điếu thuốc được không?","fa":"میشه یه سیگار بهم بدی؟"}]},{"word":"das Zimmer","en":"room","ru":"комната","vi":"căn phòng","fa":"اتاق","examples":[{"de":"Mein Zimmer ist klein, aber gemütlich.","en":"My room is small but cozy.","ru":"Моя комната маленькая, но уютная.","vi":"Phòng của tôi nhỏ nhưng ấm cúng.","fa":"اتاق من کوچک اما دنج است."},{"de":"Wir haben ein Zimmer im Hotel reserviert.","en":"We booked a room at the hotel.","ru":"Мы забронировали номер в отеле.","vi":"Chúng tôi đặt phòng ở khách sạn.","fa":"ما یک اتاق در هتل رزرو کردیم."}]},{"word":"der Zins","en":"interest (on money)","ru":"проценты (по деньгам)","vi":"sự quan tâm","fa":"علاقه","examples":[{"de":"Die Bank zahlt nur einen sehr niedrigen Zins.","en":"The bank pays only a very low rate of interest.","ru":"Банк платит лишь очень низкие проценты.","vi":"Ngân hàng chỉ trả lãi suất rất thấp.","fa":"بانک فقط نرخ سود بسیار پایینی را پرداخت می کند."},{"de":"Für den Kredit muss ich jeden Monat Zinsen zahlen.","en":"I have to pay interest on the loan every month.","ru":"За кредит мне каждый месяц приходится платить проценты.","vi":"Tôi phải trả lãi vay hàng tháng.","fa":"من باید هر ماه سود وام را پرداخت کنم."},{"de":"Der Zins ist im letzten Jahr deutlich gestiegen.","en":"Interest rates have risen considerably over the past year.","ru":"Проценты за последний год заметно выросли.","vi":"Lãi suất đã tăng đáng kể trong năm qua.","fa":"نرخ بهره در سال گذشته به میزان قابل توجهی افزایش یافته است."}]},{"word":"die Zinsen (nur Pl.)","en":"interest (financial)","ru":"проценты (банковские)","vi":"tiền lãi (chỉ pl.)","fa":"بهره (فقط pl.)","examples":[{"de":"Die Bank zahlt niedrige Zinsen auf das Sparkonto.","en":"The bank pays low interest on the savings account.","ru":"Банк платит низкие проценты по сберегательному счёту.","vi":"Ngân hàng trả lãi suất thấp cho tài khoản tiết kiệm.","fa":"بانک به حساب پس انداز سود کم می پردازد."},{"de":"Wenn man einen Kredit aufnimmt, muss man Zinsen zahlen.","en":"When you take out a loan, you have to pay interest.","ru":"Если берёшь кредит, нужно платить проценты.","vi":"Khi bạn vay tiền, bạn phải trả lãi.","fa":"وقتی وام می گیرید باید بهره پرداخت کنید."}]},{"word":"der Zirkus","en":"circus","ru":"цирк","vi":"rạp xiếc","fa":"سیرک","examples":[{"de":"Die Kinder waren begeistert vom Zirkus.","en":"The children were thrilled by the circus.","ru":"Дети были в восторге от цирка.","vi":"Bọn trẻ yêu thích rạp xiếc.","fa":"بچه ها سیرک را دوست داشتند."},{"de":"Am Wochenende gehen wir in den Zirkus.","en":"On the weekend we are going to the circus.","ru":"В выходные мы идём в цирк.","vi":"Vào cuối tuần chúng tôi đi xem xiếc.","fa":"آخر هفته به سیرک می رویم."}]},{"word":"die Zitrone","en":"lemon","ru":"лимон","vi":"quả chanh","fa":"لیمو","examples":[{"de":"Der Tee schmeckt gut mit etwas Zitrone.","en":"The tea tastes good with a bit of lemon.","ru":"Чай вкусный с небольшим количеством лимона.","vi":"Trà có vị ngon với một chút chanh.","fa":"چای با کمی لیمو طعم خوبی دارد."},{"de":"Ich kaufe frische Zitronen für das Rezept.","en":"I'm buying fresh lemons for the recipe.","ru":"Я покупаю свежие лимоны для рецепта.","vi":"Tôi mua chanh tươi cho công thức nấu ăn.","fa":"من برای دستور غذا لیموی تازه می خرم."}]},{"word":"der Zivilstand","en":"marital status","ru":"семейное положение","vi":"tình trạng hôn nhân","fa":"وضعیت تاهل","examples":[{"de":"Bitte geben Sie Ihren Zivilstand im Formular an.","en":"Please state your marital status on the form.","ru":"Пожалуйста, укажите ваше семейное положение в анкете.","vi":"Vui lòng cho biết tình trạng hôn nhân của bạn trong mẫu đơn.","fa":"لطفا وضعیت تاهل خود را در فرم ذکر کنید."},{"de":"Ihr Zivilstand hat sich nach der Heirat geändert.","en":"Her marital status changed after the marriage.","ru":"Её семейное положение изменилось после свадьбы.","vi":"Tình trạng hôn nhân của cô thay đổi sau khi kết hôn.","fa":"وضعیت تاهل او پس از ازدواج تغییر کرد."}]},{"word":"das Znüni","en":"mid-morning snack (Swiss)","ru":"утренний перекус (швейцарский вариант)","vi":"bữa ăn nhẹ","fa":"میان وعده","examples":[{"de":"Um neun machen wir eine Pause für das Znüni.","en":"At nine we take a break for the morning snack.","ru":"В девять мы делаем перерыв на утренний перекус.","vi":"Lúc chín giờ chúng tôi nghỉ ngơi để ăn nhẹ.","fa":"ساعت نه برای میان وعده استراحت می کنیم."},{"de":"Die Kinder nehmen ein Znüni mit in die Schule.","en":"The children take a morning snack to school.","ru":"Дети берут утренний перекус в школу.","vi":"Trẻ em mang đồ ăn nhẹ đến trường.","fa":"بچه ها یک میان وعده به مدرسه می برند."},{"de":"Zum Znüni gibt es heute einen Apfel und ein Brötchen.","en":"For the morning snack today there's an apple and a roll.","ru":"На утренний перекус сегодня яблоко и булочка.","vi":"Hôm nay chúng ta có một quả táo và một ổ bánh mì cho bữa trưa.","fa":"امروز برای ناهار یک سیب و یک رول داریم."}]},{"word":"der Zoll","en":"customs","ru":"таможня","vi":"hải quan","fa":"گمرک","examples":[{"de":"Am Flughafen mussten wir durch den Zoll.","en":"At the airport we had to go through customs.","ru":"В аэропорту нам пришлось пройти таможню.","vi":"Chúng tôi phải làm thủ tục hải quan ở sân bay.","fa":"باید در فرودگاه از گمرک عبور می کردیم."},{"de":"Der Zoll hat das Gepäck kontrolliert.","en":"Customs checked the luggage.","ru":"Таможня проверила багаж.","vi":"Hải quan đã kiểm tra hành lý.","fa":"گمرک چمدان ها را چک کرد."}]},{"word":"die Zone","en":"zone","ru":"зона","vi":"khu vực","fa":"منطقه","examples":[{"de":"Hier beginnt die Fußgängerzone.","en":"The pedestrian zone starts here.","ru":"Здесь начинается пешеходная зона.","vi":"Khu vực dành cho người đi bộ bắt đầu từ đây.","fa":"منطقه عابر پیاده از اینجا شروع می شود."},{"de":"In dieser Zone darf man nicht parken.","en":"Parking is not allowed in this zone.","ru":"В этой зоне нельзя парковаться.","vi":"Bạn không được phép đậu xe ở khu vực này.","fa":"شما مجاز به پارک در این منطقه نیستید."}]},{"word":"der Zoo","en":"zoo","ru":"зоопарк","vi":"sở thú","fa":"باغ وحش","examples":[{"de":"Am Sonntag besuchen wir den Zoo.","en":"On Sunday we are visiting the zoo.","ru":"В воскресенье мы посещаем зоопарк.","vi":"Vào chủ nhật chúng tôi đi thăm sở thú.","fa":"یکشنبه از باغ وحش بازدید می کنیم."},{"de":"Im Zoo gibt es viele exotische Tiere.","en":"There are many exotic animals at the zoo.","ru":"В зоопарке много экзотических животных.","vi":"Có rất nhiều động vật kỳ lạ trong sở thú.","fa":"حیوانات عجیب و غریب زیادی در باغ وحش وجود دارد."}]},{"word":"zu","en":"to; too","ru":"к, в; слишком","vi":"để","fa":"به","examples":[{"de":"Ich gehe heute Abend zu meiner Freundin.","en":"I'm going to my girlfriend's place tonight.","ru":"Сегодня вечером я иду к своей подруге.","vi":"Tối nay tôi sẽ đến nhà bạn gái tôi.","fa":"من امشب میرم پیش دوست دخترم"},{"de":"Der Kaffee ist mir zu heiß.","en":"The coffee is too hot for me.","ru":"Кофе для меня слишком горячий.","vi":"Cà phê quá nóng đối với tôi.","fa":"قهوه برای من خیلی داغ است."}]},{"word":"zu sein","en":"to be closed","ru":"быть закрытым","vi":"được","fa":"بودن","examples":[{"de":"Das Geschäft ist sonntags immer zu.","en":"The shop is always closed on Sundays.","ru":"Магазин всегда закрыт по воскресеньям.","vi":"Cửa hàng luôn đóng cửa vào ngày chủ nhật.","fa":"فروشگاه همیشه یکشنبه ها تعطیل است."},{"de":"Die Tür war die ganze Nacht zu.","en":"The door was closed all night.","ru":"Дверь была закрыта всю ночь.","vi":"Cánh cửa đóng suốt đêm.","fa":"در تمام شب بسته بود."}]},{"word":"zubereiten","en":"to prepare (food)","ru":"готовить (еду)","vi":"chuẩn bị","fa":"آماده کردن","examples":[{"de":"Meine Oma bereitet das Essen mit viel Liebe zu.","en":"My grandma prepares the food with a lot of love.","ru":"Моя бабушка готовит еду с большой любовью.","vi":"Bà tôi chuẩn bị đồ ăn với rất nhiều tình yêu thương.","fa":"مادربزرگم با عشق زیاد غذا درست می کند."},{"de":"Wie bereitet man diese Suppe zu?","en":"How do you prepare this soup?","ru":"Как готовят этот суп?","vi":"Bạn chuẩn bị món súp này như thế nào?","fa":"این سوپ را چگونه تهیه می کنید؟"}]},{"word":"der Zucker","en":"sugar","ru":"сахар","vi":"đường","fa":"شکر","examples":[{"de":"Ich trinke meinen Kaffee ohne Zucker.","en":"I drink my coffee without sugar.","ru":"Я пью свой кофе без сахара.","vi":"Tôi uống cà phê không đường.","fa":"من قهوه ام را بدون قند می نوشم."},{"de":"Zu viel Zucker ist ungesund.","en":"Too much sugar is unhealthy.","ru":"Слишком много сахара вредно для здоровья.","vi":"Quá nhiều đường không tốt cho sức khỏe.","fa":"قند بیش از حد ناسالم است."}]},{"word":"zuckerfrei","en":"sugar-free","ru":"без сахара","vi":"không đường","fa":"بدون قند","examples":[{"de":"Ich trinke nur zuckerfreie Limonade.","en":"I only drink sugar-free lemonade.","ru":"Я пью только лимонад без сахара.","vi":"Tôi chỉ uống nước chanh không đường.","fa":"من فقط لیموناد بدون قند میخورم."},{"de":"Diese Bonbons sind zuckerfrei.","en":"These sweets are sugar-free.","ru":"Эти конфеты без сахара.","vi":"Những loại kẹo này không có đường.","fa":"این شیرینی ها بدون قند هستند."},{"de":"Gibt es hier auch zuckerfreien Kuchen?","en":"Is there sugar-free cake here too?","ru":"Здесь есть и торт без сахара?","vi":"Ở đây có bánh không đường không?","fa":"کیک های بدون شکر اینجا هست؟"}]},{"word":"zudem","en":"moreover; in addition","ru":"кроме того; к тому же","vi":"cũng","fa":"همچنین","examples":[{"de":"Das Hotel ist günstig; zudem liegt es sehr zentral.","en":"The hotel is cheap; moreover it is very central.","ru":"Отель недорогой; к тому же он расположен в центре.","vi":"Khách sạn rẻ; Nó cũng nằm rất trung tâm.","fa":"هتل ارزان است؛ همچنین بسیار در مرکز قرار دارد."},{"de":"Er ist klug und zudem sehr fleißig.","en":"He is clever and, in addition, very hard-working.","ru":"Он умён и к тому же очень трудолюбив.","vi":"Anh ấy thông minh và cũng rất chăm chỉ.","fa":"او باهوش است و همچنین بسیار سخت کوش است."}]},{"word":"zudrehen","en":"to turn off (a tap), to turn towards","ru":"закрывать (кран), поворачивать к","vi":"lần lượt đóng cửa","fa":"بسته شود","examples":[{"de":"Bitte dreh den Wasserhahn richtig zu.","en":"Please turn the tap off properly.","ru":"Закрой, пожалуйста, кран как следует.","vi":"Vui lòng tắt vòi đúng cách.","fa":"لطفا شیر را به درستی ببندید."},{"de":"Sie hat das Gas zugedreht, bevor sie ging.","en":"She turned off the gas before she left.","ru":"Она перекрыла газ, прежде чем уйти.","vi":"Cô ấy đã tắt gas trước khi rời đi.","fa":"قبل از رفتنش گاز را خاموش کرد."},{"de":"Er drehte mir den Rücken zu.","en":"He turned his back to me.","ru":"Он повернулся ко мне спиной.","vi":"Anh quay lưng lại với tôi.","fa":"پشتش را به من کرد."}]},{"word":"zuerst","en":"first, at first","ru":"сначала","vi":"đầu tiên","fa":"اول","examples":[{"de":"Zuerst müssen wir die Karten kaufen.","en":"First we have to buy the tickets.","ru":"Сначала нам нужно купить билеты.","vi":"Đầu tiên chúng ta phải mua vé.","fa":"ابتدا باید بلیط ها را بخریم."},{"de":"Ich dachte zuerst, er scherzt.","en":"At first I thought he was joking.","ru":"Сначала я подумал, что он шутит.","vi":"Lúc đầu tôi tưởng anh ấy nói đùa.","fa":"اول فکر کردم شوخی می کند."}]},{"word":"Zuerst spreche ich über …","en":"First I'll talk about … (structuring)","ru":"Сначала я расскажу о … (структура)","vi":"Đầu tiên tôi sẽ nói về…","fa":"ابتدا در مورد…","examples":[{"de":"Zuerst spreche ich über die Vorteile.","en":"First I'll talk about the advantages.","ru":"Сначала я расскажу о преимуществах.","vi":"Đầu tiên tôi sẽ nói về lợi ích.","fa":"ابتدا در مورد مزایا صحبت خواهم کرد."}]},{"word":"der Zufall","en":"coincidence","ru":"случайность, совпадение","vi":"sự trùng hợp ngẫu nhiên","fa":"تصادف","examples":[{"de":"Es war reiner Zufall, dass wir uns getroffen haben.","en":"It was pure coincidence that we met.","ru":"Это было чистой случайностью, что мы встретились.","vi":"Việc chúng tôi gặp nhau hoàn toàn là sự trùng hợp ngẫu nhiên.","fa":"این کاملا تصادفی بود که با هم آشنا شدیم."},{"de":"So ein Zufall, dich hier zu sehen!","en":"What a coincidence to see you here!","ru":"Какое совпадение увидеть тебя здесь!","vi":"Thật trùng hợp khi gặp bạn ở đây!","fa":"چنین تصادفی است که شما را اینجا می بینم!"}]},{"word":"zufällig","en":"by chance; random","ru":"случайный; случайно","vi":"ngẫu nhiên","fa":"تصادفی","examples":[{"de":"Wir haben uns rein zufällig getroffen.","en":"We met purely by chance.","ru":"Мы встретились совершенно случайно.","vi":"Chúng tôi gặp nhau hoàn toàn tình cờ.","fa":"ما کاملا تصادفی با هم آشنا شدیم."},{"de":"Weißt du zufällig, wie spät es ist?","en":"Do you happen to know what time it is?","ru":"Ты, случайно, не знаешь, который час?","vi":"Bạn có biết bây giờ là mấy giờ không?","fa":"آیا می دانید ساعت چند است؟"}]},{"word":"zufrieden","en":"satisfied, content","ru":"довольный","vi":"hài lòng","fa":"راضی","examples":[{"de":"Ich bin mit meiner neuen Arbeit sehr zufrieden.","en":"I am very satisfied with my new job.","ru":"Я очень доволен своей новой работой.","vi":"Tôi rất hài lòng với công việc mới của tôi.","fa":"من از شغل جدیدم بسیار راضی هستم."},{"de":"Der Kunde war mit dem Service nicht zufrieden.","en":"The customer was not satisfied with the service.","ru":"Клиент был недоволен обслуживанием.","vi":"Khách hàng không hài lòng với dịch vụ.","fa":"مشتری از خدمات راضی نبود."}]},{"word":"die Zufriedenheit","en":"satisfaction; contentment","ru":"удовлетворённость; довольство","vi":"sự hài lòng","fa":"رضایت","examples":[{"de":"Die Zufriedenheit der Kunden ist uns wichtig.","en":"Customer satisfaction is important to us.","ru":"Удовлетворённость клиентов важна для нас.","vi":"Sự hài lòng của khách hàng là quan trọng đối với chúng tôi.","fa":"رضایت مشتری برای ما مهم است."},{"de":"Er strahlte vor Zufriedenheit.","en":"He was beaming with contentment.","ru":"Он сиял от довольства.","vi":"Anh cười rạng rỡ với sự hài lòng.","fa":"او از رضایت برق زد."}]},{"word":"der Zug","en":"train","ru":"поезд","vi":"tàu hỏa; chuyến tàu","fa":"قطار","examples":[{"de":"Der Zug nach München fährt um acht Uhr ab.","en":"The train to Munich departs at eight o'clock.","ru":"Поезд в Мюнхен отправляется в восемь часов.","vi":"Chuyến tàu tới Munich khởi hành lúc 8 giờ.","fa":"قطار به مونیخ ساعت هشت حرکت می کند."},{"de":"Ich habe den Zug verpasst.","en":"I missed the train.","ru":"Я опоздал на поезд.","vi":"Tôi đã lỡ chuyến tàu.","fa":"قطار را از دست دادم."}]},{"word":"der Zugang","en":"access","ru":"доступ","vi":"quyền truy cập","fa":"دسترسی","examples":[{"de":"Der Zugang zum Gebäude ist nur mit Ausweis möglich.","en":"Access to the building is only possible with an ID.","ru":"Доступ в здание возможен только с удостоверением личности.","vi":"Chỉ có thể vào tòa nhà bằng ID.","fa":"دسترسی به ساختمان فقط با شناسه امکان پذیر است."},{"de":"Wir haben keinen Zugang zum Internet.","en":"We have no access to the internet.","ru":"У нас нет доступа к интернету.","vi":"Chúng tôi không có quyền truy cập vào internet.","fa":"ما به اینترنت دسترسی نداریم"}]},{"word":"zugänglich","en":"accessible, approachable","ru":"доступный","vi":"có thể truy cập","fa":"قابل دسترس","examples":[{"de":"Das Gebäude ist für Rollstuhlfahrer zugänglich.","en":"The building is accessible for wheelchair users.","ru":"Здание доступно для инвалидов-колясочников.","vi":"Tòa nhà có lối đi cho xe lăn.","fa":"این ساختمان با ویلچر قابل دسترسی است."},{"de":"Diese Informationen sind öffentlich zugänglich.","en":"This information is publicly accessible.","ru":"Эта информация общедоступна.","vi":"Thông tin này có sẵn công khai.","fa":"این اطلاعات در دسترس عموم است."},{"de":"Sie ist ein offener und zugänglicher Mensch.","en":"She is an open and approachable person.","ru":"Она открытый и приветливый человек.","vi":"Cô ấy là một người cởi mở và dễ gần.","fa":"او فردی باز و قابل برخورد است."}]},{"word":"zugeben","en":"to admit","ru":"признавать","vi":"thừa nhận","fa":"اعتراف","examples":[{"de":"Er wollte seinen Fehler zuerst nicht zugeben.","en":"At first he didn't want to admit his mistake.","ru":"Сначала он не хотел признавать свою ошибку.","vi":"Lúc đầu anh ấy không muốn thừa nhận sai lầm của mình.","fa":"او ابتدا نمی خواست اشتباه خود را بپذیرد."},{"de":"Ich muss zugeben, dass du recht hattest.","en":"I have to admit that you were right.","ru":"Я должен признать, что ты был прав.","vi":"Tôi phải thừa nhận rằng bạn đã đúng.","fa":"باید اعتراف کنم که حق با شما بود."}]},{"word":"zugehen","en":"to close; to approach","ru":"закрываться; приближаться","vi":"cách tiếp cận","fa":"رویکرد","examples":[{"de":"Die Tür geht nicht richtig zu.","en":"The door doesn't close properly.","ru":"Дверь не закрывается как следует.","vi":"Cửa không đóng đúng cách.","fa":"در به درستی بسته نمی شود."},{"de":"Er ging langsam auf mich zu.","en":"He slowly approached me.","ru":"Он медленно подходил ко мне.","vi":"Anh ấy từ từ bước về phía tôi.","fa":"آهسته به سمتم رفت."}]},{"word":"zügig","en":"swift, brisk, prompt","ru":"быстрый, оперативный (о продвижении)","vi":"nhanh chóng","fa":"به سرعت","examples":[{"de":"Wir sollten zügig vorankommen.","en":"We should make brisk progress.","ru":"Нам следует быстро продвигаться.","vi":"Chúng ta nên tiến về phía trước một cách nhanh chóng.","fa":"باید سریع جلو برویم"},{"de":"Bitte bearbeiten Sie den Antrag zügig.","en":"Please process the application promptly.","ru":"Пожалуйста, оперативно обработайте заявление.","vi":"Hãy nhanh chóng xử lý đơn đăng ký.","fa":"لطفا به سرعت برنامه را پردازش کنید."},{"de":"Er ging zügig zur Arbeit.","en":"He walked briskly to work.","ru":"Он быстрым шагом пошёл на работу.","vi":"Anh nhanh chóng đi làm.","fa":"سریع رفت سر کار."}]},{"word":"das Zuhause","en":"home","ru":"дом, домашний очаг","vi":"ngôi nhà","fa":"خانه","examples":[{"de":"Nach der langen Reise war ich froh, wieder zu Hause zu sein.","en":"After the long journey I was happy to be home again.","ru":"После долгого путешествия я был рад снова оказаться дома.","vi":"Sau chuyến đi dài, tôi vui mừng được trở về nhà.","fa":"بعد از سفر طولانی، خوشحال شدم که دوباره به خانه برگشتم."},{"de":"Jedes Kind braucht ein sicheres Zuhause.","en":"Every child needs a safe home.","ru":"Каждому ребёнку нужен безопасный дом.","vi":"Mỗi đứa trẻ đều cần một ngôi nhà an toàn.","fa":"هر کودکی به یک خانه امن نیاز دارد."}]},{"word":"zuhören","en":"to listen","ru":"слушать","vi":"lắng nghe","fa":"گوش کن","examples":[{"de":"Bitte hör mir kurz zu.","en":"Please listen to me for a moment.","ru":"Пожалуйста, послушай меня минутку.","vi":"Xin hãy lắng nghe tôi một lát.","fa":"لطفا یک لحظه به من گوش کن"},{"de":"Er hört seinen Schülern immer aufmerksam zu.","en":"He always listens attentively to his students.","ru":"Он всегда внимательно слушает своих учеников.","vi":"Ông luôn lắng nghe cẩn thận các học trò của mình.","fa":"او همیشه با دقت به صحبت های شاگردانش گوش می دهد."}]},{"word":"der Zuhörer","en":"listener (male)","ru":"слушатель (мужчина)","vi":"người nghe","fa":"شنونده","examples":[{"de":"Der Redner fesselte seine Zuhörer von Anfang an.","en":"The speaker captivated his listeners from the start.","ru":"Оратор увлёк своих слушателей с самого начала.","vi":"Người diễn thuyết đã thu hút người nghe ngay từ đầu.","fa":"سخنران از همان ابتدا شنوندگان خود را مجذوب خود کرد."},{"de":"Als guter Zuhörer unterbricht er nie.","en":"As a good listener he never interrupts.","ru":"Как хороший слушатель он никогда не перебивает.","vi":"Là một người biết lắng nghe, anh ấy không bao giờ ngắt lời.","fa":"یک شنونده خوب، هرگز حرفش را قطع نمی کند."},{"de":"Die Zuhörer stellten viele Fragen.","en":"The listeners asked many questions.","ru":"Слушатели задавали много вопросов.","vi":"Khán giả đặt nhiều câu hỏi.","fa":"حضار سوالات زیادی پرسیدند."}]},{"word":"die Zuhörerin","en":"listener (female)","ru":"слушательница (женщина)","vi":"người nghe","fa":"شنونده","examples":[{"de":"Die Zuhörerin nickte zustimmend.","en":"The listener nodded in agreement.","ru":"Слушательница согласно кивнула.","vi":"Người nghe gật đầu đồng ý.","fa":"شنونده سری به تایید تکان داد."},{"de":"Sie ist eine geduldige Zuhörerin.","en":"She is a patient listener.","ru":"Она терпеливая слушательница.","vi":"Cô ấy là một người kiên nhẫn lắng nghe.","fa":"او یک شنونده صبور است."},{"de":"Jede Zuhörerin bekam ein Programmheft.","en":"Each listener received a programme booklet.","ru":"Каждая слушательница получила программку.","vi":"Mỗi thính giả nhận được một tập sách chương trình.","fa":"هر شنونده یک کتابچه برنامه دریافت کرد."}]},{"word":"die Zukunft","en":"future","ru":"будущее","vi":"tương lai","fa":"آینده","examples":[{"de":"Niemand weiß genau, was die Zukunft bringt.","en":"Nobody knows exactly what the future will bring.","ru":"Никто точно не знает, что принесёт будущее.","vi":"Không ai biết chính xác những gì tương lai sẽ mang lại.","fa":"هیچ کس دقیقاً نمی داند آینده چه چیزی را به همراه خواهد داشت."},{"de":"Sie plant ihre Zukunft sehr sorgfältig.","en":"She plans her future very carefully.","ru":"Она очень тщательно планирует своё будущее.","vi":"Cô ấy lên kế hoạch cho tương lai của mình rất cẩn thận.","fa":"او با دقت زیادی برای آینده خود برنامه ریزی می کند."}]},{"word":"zukünftig","en":"future (adj.)","ru":"будущий","vi":"trong tương lai","fa":"در آینده","examples":[{"de":"Mein zukünftiger Mann kommt aus Spanien.","en":"My future husband is from Spain.","ru":"Мой будущий муж родом из Испании.","vi":"Chồng tương lai của tôi đến từ Tây Ban Nha.","fa":"شوهر آینده من اهل اسپانیا است."},{"de":"Zukünftig werde ich früher aufstehen.","en":"In the future I will get up earlier.","ru":"В будущем я буду вставать раньше.","vi":"Trong tương lai tôi sẽ dậy sớm hơn.","fa":"در آینده زودتر بیدار خواهم شد."}]},{"word":"die Zukunftsperspektive","en":"future prospect, outlook","ru":"перспектива на будущее","vi":"viễn cảnh tương lai","fa":"چشم انداز آینده","examples":[{"de":"Der Beruf bietet gute Zukunftsperspektiven.","en":"The profession offers good future prospects.","ru":"Профессия предлагает хорошие перспективы на будущее.","vi":"Nghề nghiệp mang lại triển vọng tốt đẹp trong tương lai.","fa":"این حرفه چشم اندازهای آینده خوبی را ارائه می دهد."},{"de":"Ohne Ausbildung sind die Zukunftsperspektiven begrenzt.","en":"Without training the future prospects are limited.","ru":"Без образования перспективы на будущее ограничены.","vi":"Không được đào tạo, triển vọng tương lai bị hạn chế.","fa":"بدون آموزش، چشم اندازهای آینده محدود است."},{"de":"Junge Leute fragen oft nach ihrer Zukunftsperspektive.","en":"Young people often ask about their future prospects.","ru":"Молодые люди часто спрашивают о своих перспективах.","vi":"Những người trẻ thường hỏi về triển vọng tương lai của họ.","fa":"جوانان اغلب در مورد آینده خود می پرسند."}]},{"word":"die Zulassungsbescheinigung","en":"vehicle registration certificate","ru":"свидетельство о регистрации транспортного средства","vi":"giấy chứng nhận đăng ký","fa":"گواهی ثبت نام","examples":[{"de":"Die Zulassungsbescheinigung muss immer im Auto sein.","en":"The registration certificate must always be in the car.","ru":"Свидетельство о регистрации всегда должно быть в машине.","vi":"Giấy đăng ký phải luôn ở trên xe.","fa":"گواهی ثبت نام باید همیشه در خودرو باشد."},{"de":"Bei der Kontrolle zeigte er seine Zulassungsbescheinigung.","en":"At the check he showed his registration certificate.","ru":"При проверке он показал свидетельство о регистрации.","vi":"Trong quá trình kiểm tra, anh ta đã xuất trình giấy chứng nhận đăng ký của mình.","fa":"در بازرسی گواهی ثبت نام خود را نشان داد."},{"de":"Ohne Zulassungsbescheinigung darfst du nicht fahren.","en":"Without the registration certificate you may not drive.","ru":"Без свидетельства о регистрации ездить нельзя.","vi":"Bạn không được phép lái xe mà không có giấy chứng nhận đăng ký.","fa":"شما مجاز به رانندگی بدون گواهی ثبت نام نیستید."}]},{"word":"zuletzt","en":"last, finally","ru":"в конце концов, напоследок","vi":"cuối cùng","fa":"آخرین","examples":[{"de":"Zuletzt möchte ich mich bei allen bedanken.","en":"Finally, I would like to thank everyone.","ru":"Напоследок я хотел бы поблагодарить всех.","vi":"Cuối cùng tôi xin gửi lời cảm ơn tới tất cả mọi người.","fa":"در آخر از همه تشکر می کنم."},{"de":"Wann hast du sie zuletzt gesehen?","en":"When did you last see her?","ru":"Когда ты видел её в последний раз?","vi":"Lần cuối cùng bạn nhìn thấy cô ấy là khi nào?","fa":"آخرین بار کی او را دیدی؟"}]},{"word":"Zum Beispiel …","en":"For example … (giving an example)","ru":"Например … (пример)","vi":"Ví dụ như…","fa":"به عنوان مثال…","examples":[{"de":"Man kann viel sparen, zum Beispiel beim Strom.","en":"You can save a lot, for example on electricity.","ru":"Можно много экономить, например, на электричестве.","vi":"Bạn có thể tiết kiệm rất nhiều, ví dụ như về điện.","fa":"شما می توانید مقدار زیادی صرفه جویی کنید، به عنوان مثال در برق."}]},{"word":"Zum Schluss möchte ich sagen, dass …","en":"Finally, I'd like to say that … (concluding)","ru":"В заключение я хотел бы сказать, что … (завершение)","vi":"Cuối cùng, tôi muốn nói rằng…","fa":"در پایان می خواهم بگویم که …","examples":[{"de":"Zum Schluss möchte ich sagen, dass sich das Thema lohnt.","en":"Finally, I'd like to say that the topic is worthwhile.","ru":"В заключение я хотел бы сказать, что эта тема того стоит.","vi":"Cuối cùng, tôi muốn nói rằng chủ đề này rất đáng giá.","fa":"در پایان می خواهم بگویم که موضوع ارزشش را دارد."}]},{"word":"zumachen","en":"to close","ru":"закрывать","vi":"đóng","fa":"بستن","examples":[{"de":"Kannst du bitte das Fenster zumachen?","en":"Can you please close the window?","ru":"Ты можешь, пожалуйста, закрыть окно?","vi":"Bạn có thể vui lòng đóng cửa sổ được không?","fa":"میشه لطفا پنجره رو ببندید؟"},{"de":"Der Laden macht um achtzehn Uhr zu.","en":"The shop closes at six p.m.","ru":"Магазин закрывается в шесть вечера.","vi":"Cửa hàng đóng cửa lúc 6 giờ chiều.","fa":"ساعت 6 عصر مغازه بسته می شود."}]},{"word":"zumindest","en":"at least","ru":"по крайней мере","vi":"ít nhất","fa":"حداقل","examples":[{"de":"Wir sollten zumindest versuchen, pünktlich zu sein.","en":"We should at least try to be on time.","ru":"Нам следует хотя бы попытаться быть вовремя.","vi":"Ít nhất chúng ta nên cố gắng đến đúng giờ.","fa":"حداقل باید سعی کنیم به موقع برسیم."},{"de":"Er hat zumindest angerufen, um sich zu entschuldigen.","en":"He at least called to apologize.","ru":"Он хотя бы позвонил, чтобы извиниться.","vi":"Ít nhất thì anh ấy cũng gọi điện để xin lỗi.","fa":"حداقل زنگ زد تا عذرخواهی کند."}]},{"word":"zunächst","en":"first of all, for now","ru":"сначала, прежде всего","vi":"ban đầu","fa":"در ابتدا","examples":[{"de":"Zunächst möchte ich Ihnen unser Team vorstellen.","en":"First of all, I would like to introduce our team to you.","ru":"Прежде всего я хотел бы представить вам нашу команду.","vi":"Trước hết, tôi muốn giới thiệu đội ngũ của chúng tôi với bạn.","fa":"اول از همه می خواهم تیم ما را به شما معرفی کنم."},{"de":"Zunächst bleibt alles beim Alten.","en":"For now, everything stays the same.","ru":"Пока всё остаётся по-старому.","vi":"Lúc đầu mọi thứ vẫn như cũ.","fa":"در ابتدا همه چیز ثابت می ماند."}]},{"word":"die Zünder","en":"detonator, fuse","ru":"запал, детонатор","vi":"ngòi nổ","fa":"چاشنی ها","examples":[{"de":"Die Feuerwerkskörper haben einen empfindlichen Zünder.","en":"The fireworks have a sensitive fuse.","ru":"У этих фейерверков чувствительный запал.","vi":"Pháo hoa có bộ phận đánh lửa nhạy cảm.","fa":"آتش بازی دارای یک محترقه حساس است."},{"de":"Die Polizei fand mehrere Zünder in der Fabrik.","en":"The police found several detonators in the factory.","ru":"Полиция нашла несколько детонаторов на фабрике.","vi":"Cảnh sát tìm thấy một số ngòi nổ trong nhà máy.","fa":"پلیس چندین چاشنی را در کارخانه پیدا کرد."}]},{"word":"das Zündholz","en":"match","ru":"спичка","vi":"trận đấu","fa":"کبریت","examples":[{"de":"Hast du ein Zündholz, um die Kerze anzuzünden?","en":"Do you have a match to light the candle?","ru":"У тебя есть спичка, чтобы зажечь свечу?","vi":"Bạn có diêm để thắp nến không?","fa":"آیا برای روشن کردن شمع کبریت دارید؟"},{"de":"Die Zündhölzer liegen in der Küchenschublade.","en":"The matches are in the kitchen drawer.","ru":"Спички лежат в кухонном ящике.","vi":"Que diêm ở trong ngăn kéo nhà bếp.","fa":"کبریت ها در کشوی آشپزخانه هستند."}]},{"word":"zunehmen","en":"to gain weight; to increase","ru":"набирать вес; увеличиваться","vi":"tăng lên","fa":"افزایش دهد","examples":[{"de":"Im Urlaub habe ich leider drei Kilo zugenommen.","en":"Unfortunately I gained three kilos on vacation.","ru":"К сожалению, во время отпуска я набрал три килограмма.","vi":"Thật không may, tôi đã tăng ba kg trong kỳ nghỉ của mình.","fa":"متأسفانه در تعطیلاتم سه کیلو اضافه وزن پیدا کردم."},{"de":"Die Zahl der Touristen nimmt jedes Jahr zu.","en":"The number of tourists increases every year.","ru":"Число туристов увеличивается каждый год.","vi":"Số lượng khách du lịch đang tăng lên hàng năm.","fa":"هر سال بر تعداد گردشگران افزوده می شود."}]},{"word":"zurechtkommen","en":"to cope, to manage","ru":"справляться","vi":"đối phó","fa":"کنار آمدن","examples":[{"de":"Kommst du mit dem neuen Programm gut zurecht?","en":"Are you coping well with the new program?","ru":"Ты хорошо справляешься с новой программой?","vi":"Bạn có hòa nhập tốt với chương trình mới không?","fa":"آیا با برنامه جدید به خوبی کنار می آیید؟"},{"de":"Sie kommt mit wenig Geld gut zurecht.","en":"She manages well with little money.","ru":"Она хорошо справляется с небольшими деньгами.","vi":"Cô ấy sống tốt với ít tiền.","fa":"او با پول کم به خوبی کنار می آید."}]},{"word":"zurück","en":"back","ru":"назад, обратно","vi":"trở lại","fa":"برگشت","examples":[{"de":"Wann kommst du von der Arbeit zurück?","en":"When are you coming back from work?","ru":"Когда ты вернёшься с работы?","vi":"Khi nào bạn đi làm về?","fa":"کی از سر کار برمیگردی؟"},{"de":"Ich gebe dir das Buch morgen zurück.","en":"I'll give the book back to you tomorrow.","ru":"Я верну тебе книгу завтра.","vi":"Tôi sẽ trả lại bạn cuốn sách vào ngày mai.","fa":"کتاب را فردا به شما پس می دهم."}]},{"word":"zurückhaltend","en":"reserved, reticent, restrained","ru":"сдержанный, осторожный","vi":"dành riêng","fa":"رزرو شده است","examples":[{"de":"In Gesprächen ist er eher zurückhaltend.","en":"In conversations he is rather reserved.","ru":"В разговорах он скорее сдержан.","vi":"Anh ấy khá dè dặt trong các cuộc trò chuyện.","fa":"او در گفتگوها نسبتا محتاط است."},{"de":"Sie reagierte sehr zurückhaltend auf das Angebot.","en":"She reacted very cautiously to the offer.","ru":"Она очень осторожно отреагировала на предложение.","vi":"Cô ấy phản ứng rất thận trọng với lời đề nghị.","fa":"او بسیار محتاطانه به این پیشنهاد واکنش نشان داد."},{"de":"Die Anleger blieben zurückhaltend.","en":"The investors remained cautious.","ru":"Инвесторы оставались осторожными.","vi":"Nhà đầu tư vẫn thận trọng.","fa":"سرمایه گذاران محتاط ماندند."}]},{"word":"zurzeit","en":"currently, at the moment","ru":"в настоящее время, сейчас","vi":"hiện tại","fa":"در حال حاضر","examples":[{"de":"Zurzeit arbeite ich an einem neuen Projekt.","en":"I am currently working on a new project.","ru":"Сейчас я работаю над новым проектом.","vi":"Tôi hiện đang làm việc trên một dự án mới.","fa":"من در حال حاضر روی یک پروژه جدید کار می کنم."},{"de":"Zurzeit ist sie im Urlaub.","en":"At the moment she is on vacation.","ru":"В настоящее время она в отпуске.","vi":"Cô ấy hiện đang đi nghỉ.","fa":"او در حال حاضر در تعطیلات است."}]},{"word":"die Zusage","en":"acceptance, promise (positive reply)","ru":"согласие, обещание (положительный ответ)","vi":"lời hứa","fa":"وعده","examples":[{"de":"Endlich habe ich die Zusage für die Stelle bekommen.","en":"At last I got the offer for the job.","ru":"Наконец я получил согласие на работу.","vi":"Cuối cùng tôi đã nhận được lời đề nghị cho vị trí này.","fa":"بالاخره پیشنهاد این موقعیت را گرفتم."},{"de":"Ihre Zusage hat mich sehr gefreut.","en":"Her acceptance pleased me a lot.","ru":"Её согласие меня очень обрадовало.","vi":"Tôi rất hài lòng với sự chấp nhận của bạn.","fa":"از قبولی شما بسیار خوشحال شدم."},{"de":"Wir warten noch auf deine Zusage.","en":"We're still waiting for your acceptance.","ru":"Мы всё ещё ждём вашего согласия.","vi":"Chúng tôi vẫn đang chờ xác nhận của bạn.","fa":"ما همچنان منتظر تایید شما هستیم."}]},{"word":"zusagen","en":"to accept (an invitation); to promise","ru":"соглашаться, обещать","vi":"lời hứa","fa":"قول دادن","examples":[{"de":"Ich habe der Einladung schon zugesagt.","en":"I have already accepted the invitation.","ru":"Я уже принял приглашение.","vi":"Tôi đã chấp nhận lời mời rồi.","fa":"من قبلا دعوت را پذیرفته ام."},{"de":"Er hat mir zugesagt, pünktlich zu kommen.","en":"He promised me to come on time.","ru":"Он пообещал мне прийти вовремя.","vi":"Anh ấy hứa với tôi rằng anh ấy sẽ đến đúng giờ.","fa":"او به من قول داد که به موقع بیاید."}]},{"word":"zusammen","en":"together","ru":"вместе","vi":"cùng với nhau","fa":"با هم","examples":[{"de":"Wir kochen heute Abend zusammen.","en":"We are cooking together tonight.","ru":"Сегодня вечером мы готовим вместе.","vi":"Tối nay chúng ta cùng nấu ăn nhé.","fa":"امشب با هم آشپزی می کنیم."},{"de":"Sie leben seit fünf Jahren zusammen.","en":"They have been living together for five years.","ru":"Они живут вместе уже пять лет.","vi":"Họ đã sống với nhau được năm năm.","fa":"آنها پنج سال است که با هم زندگی می کنند."}]},{"word":"zusammen-","en":"together (separable verb prefix: jointly, with each other)","ru":"вместе (отделяемая приставка: совместно, друг с другом)","vi":"cùng nhau-","fa":"با هم -","examples":[{"de":"Wir arbeiten gern zusammen.","en":"We like working together.","ru":"Мы любим работать вместе.","vi":"Chúng tôi thích làm việc cùng nhau.","fa":"ما از کار با هم لذت می بریم."},{"de":"Lass uns die Sachen zusammenpacken.","en":"Let's pack the things together.","ru":"Давай упакуем вещи вместе.","vi":"Hãy thu dọn đồ đạc đi.","fa":"بیایید وسایل را جمع کنیم."},{"de":"Sie wohnen seit drei Jahren zusammen.","en":"They have been living together for three years.","ru":"Они живут вместе уже три года.","vi":"Họ đã sống với nhau được ba năm.","fa":"آنها سه سال با هم زندگی کرده اند."}]},{"word":"die Zusammenarbeit","en":"cooperation, collaboration","ru":"сотрудничество, совместная работа","vi":"sự hợp tác","fa":"همکاری","examples":[{"de":"Die Zusammenarbeit mit dem neuen Kollegen läuft sehr gut.","en":"The collaboration with the new colleague is going very well.","ru":"Сотрудничество с новым коллегой идёт очень хорошо.","vi":"Sự hợp tác với đồng nghiệp mới đang diễn ra rất tốt đẹp.","fa":"همکاری با همکار جدید بسیار خوب پیش می رود."},{"de":"Eine enge Zusammenarbeit zwischen den Abteilungen ist wichtig.","en":"Close cooperation between the departments is important.","ru":"Тесное сотрудничество между отделами очень важно.","vi":"Sự hợp tác chặt chẽ giữa các phòng ban là rất quan trọng.","fa":"همکاری نزدیک بین بخش ها مهم است."},{"de":"Wir freuen uns auf die weitere Zusammenarbeit mit Ihnen.","en":"We look forward to continuing our cooperation with you.","ru":"Мы рады продолжить с вами сотрудничество.","vi":"Chúng tôi mong được tiếp tục làm việc với bạn.","fa":"ما مشتاقانه منتظر ادامه همکاری با شما هستیم."}]},{"word":"der Zusammenbruch","en":"collapse, breakdown","ru":"крах, обвал, срыв","vi":"sự sụp đổ","fa":"فروپاشی","examples":[{"de":"Der Zusammenbruch der Börse traf viele Anleger.","en":"The collapse of the stock market hit many investors.","ru":"Обвал биржи ударил по многим инвесторам.","vi":"Sự sụp đổ của thị trường chứng khoán ảnh hưởng đến nhiều nhà đầu tư.","fa":"سقوط بازار سهام بسیاری از سرمایه گذاران را تحت تاثیر قرار داد."},{"de":"Nach dem Krieg kam der wirtschaftliche Zusammenbruch.","en":"After the war came the economic collapse.","ru":"После войны наступил экономический крах.","vi":"Sau chiến tranh là nền kinh tế suy thoái.","fa":"پس از جنگ، سقوط اقتصادی رخ داد."},{"de":"Er stand kurz vor dem nervlichen Zusammenbruch.","en":"He was on the verge of a nervous breakdown.","ru":"Он был на грани нервного срыва.","vi":"Anh ấy đang trên bờ vực suy nhược thần kinh.","fa":"او در آستانه یک حمله عصبی بود."}]},{"word":"zusammenfassen","en":"to summarise","ru":"подытоживать, резюмировать","vi":"tóm tắt","fa":"خلاصه کردن","examples":[{"de":"Kannst du den Text kurz zusammenfassen?","en":"Can you summarise the text briefly?","ru":"Можешь кратко резюмировать текст?","vi":"Bạn có thể tóm tắt ngắn gọn văn bản được không?","fa":"میشه خلاصه متن رو بگید؟"},{"de":"Lassen Sie mich die Ergebnisse zusammenfassen.","en":"Let me summarise the results.","ru":"Позвольте мне подытожить результаты.","vi":"Hãy để tôi tóm tắt kết quả.","fa":"بگذارید نتایج را خلاصه کنم."},{"de":"Am Ende fasste sie die wichtigsten Punkte zusammen.","en":"At the end she summarised the most important points.","ru":"В конце она подытожила самые важные пункты.","vi":"Cuối cùng cô tóm tắt những điểm quan trọng nhất.","fa":"وی در پایان به جمع بندی مهم ترین نکات پرداخت."}]},{"word":"Zusammenfassend kann man sagen, dass …","en":"To summarise, one can say that … (summary)","ru":"Подводя итог, можно сказать, что … (резюме)","vi":"Tóm lại, có thể nói rằng…","fa":"به طور خلاصه می توان گفت که …","examples":[{"de":"Zusammenfassend kann man sagen, dass es viele Vorteile gibt.","en":"To summarise, one can say that there are many advantages.","ru":"Подводя итог, можно сказать, что преимуществ много.","vi":"Tóm lại có rất nhiều ưu điểm.","fa":"به طور خلاصه، مزایای زیادی وجود دارد."}]},{"word":"der Zusammenhalt","en":"cohesion, solidarity","ru":"сплочённость, единство","vi":"sự gắn kết","fa":"انسجام","examples":[{"de":"Der Zusammenhalt in der Familie ist sehr stark.","en":"The cohesion within the family is very strong.","ru":"Сплочённость в семье очень крепкая.","vi":"Mối liên kết trong gia đình rất bền chặt.","fa":"پیوند در خانواده بسیار قوی است."},{"de":"In Krisen zeigt sich der Zusammenhalt einer Gesellschaft.","en":"In times of crisis the cohesion of a society shows itself.","ru":"В кризисы проявляется сплочённость общества.","vi":"Sự gắn kết của một xã hội trở nên rõ ràng trong các cuộc khủng hoảng.","fa":"انسجام یک جامعه در بحران ها آشکار می شود."},{"de":"Gemeinsame Feste fördern den Zusammenhalt.","en":"Shared celebrations strengthen cohesion.","ru":"Совместные праздники укрепляют сплочённость.","vi":"Các lễ kỷ niệm chung thúc đẩy tình đoàn kết.","fa":"جشن های مشترک باعث ترویج همبستگی می شود."}]},{"word":"der Zusammenhang","en":"context, connection","ru":"связь, контекст","vi":"sự kết nối","fa":"اتصال","examples":[{"de":"Ich verstehe den Zusammenhang zwischen diesen beiden Ereignissen nicht.","en":"I don't understand the connection between these two events.","ru":"Я не понимаю связь между этими двумя событиями.","vi":"Tôi không hiểu mối liên hệ giữa hai sự kiện này.","fa":"من ارتباط بین این دو رویداد را درک نمی کنم."},{"de":"In diesem Zusammenhang ist der Bericht sehr wichtig.","en":"In this context, the report is very important.","ru":"В этом контексте отчёт очень важен.","vi":"Trong bối cảnh này, báo cáo là rất quan trọng.","fa":"در این زمینه، گزارش بسیار مهم است."}]},{"word":"das Zusammenleben","en":"living together, coexistence","ru":"совместная жизнь, сосуществование","vi":"sống cùng nhau","fa":"زندگی مشترک","examples":[{"de":"Das Zusammenleben verschiedener Kulturen kann bereichernd sein.","en":"The coexistence of different cultures can be enriching.","ru":"Сосуществование разных культур может обогащать.","vi":"Sống cùng nhau giữa các nền văn hóa khác nhau có thể trở nên phong phú.","fa":"زندگی مشترک بین فرهنگ‌های مختلف می‌تواند غنی‌کننده باشد."},{"de":"Regeln erleichtern das Zusammenleben in einer WG.","en":"Rules make living together in a shared flat easier.","ru":"Правила облегчают совместную жизнь в общей квартире.","vi":"Các quy tắc làm cho việc sống chung trong một căn hộ chung dễ dàng hơn.","fa":"قوانین زندگی مشترک در یک آپارتمان مشترک را آسان تر می کند."},{"de":"Das friedliche Zusammenleben ist nicht selbstverständlich.","en":"Peaceful coexistence is not to be taken for granted.","ru":"Мирное сосуществование не само собой разумеется.","vi":"Chung sống hòa bình không thể được coi là điều hiển nhiên.","fa":"همزیستی مسالمت آمیز را نمی توان بدیهی دانست."}]},{"word":"zusammenstellen","en":"to put together, to compile, to assemble","ru":"составлять, собирать (воедино)","vi":"tập hợp lại với nhau","fa":"کنار هم گذاشتن","examples":[{"de":"Wir stellen ein Menü für das Fest zusammen.","en":"We are putting together a menu for the party.","ru":"Мы составляем меню для праздника.","vi":"Chúng tôi đưa ra một thực đơn cho lễ hội.","fa":"ما یک منو برای جشنواره آماده کردیم."},{"de":"Sie hat eine Liste der Teilnehmer zusammengestellt.","en":"She compiled a list of the participants.","ru":"Она составила список участников.","vi":"Cô đã biên soạn một danh sách những người tham gia.","fa":"او فهرستی از شرکت کنندگان تهیه کرد."},{"de":"Kannst du mir ein paar Beispiele zusammenstellen?","en":"Can you put together a few examples for me?","ru":"Можешь подобрать мне несколько примеров?","vi":"Bạn có thể đưa ra một vài ví dụ cho tôi được không?","fa":"می توانید چند مثال برای من بچینید؟"}]},{"word":"zusätzlich","en":"additional","ru":"дополнительный","vi":"thêm vào đó","fa":"علاوه بر این","examples":[{"de":"Wir brauchen zusätzliche Informationen.","en":"We need additional information.","ru":"Нам нужна дополнительная информация.","vi":"Chúng tôi cần thêm thông tin.","fa":"به اطلاعات تکمیلی نیاز داریم"},{"de":"Für den Kurs fallen zusätzliche Kosten an.","en":"Additional costs arise for the course.","ru":"За курс взимаются дополнительные расходы.","vi":"Có thêm chi phí cho khóa học.","fa":"هزینه های اضافی برای دوره وجود دارد."}]},{"word":"zuschauen","en":"to watch, to look on","ru":"наблюдать, смотреть","vi":"xem","fa":"تماشا کن","examples":[{"de":"Die Kinder schauen den Vögeln im Park zu.","en":"The children are watching the birds in the park.","ru":"Дети наблюдают за птицами в парке.","vi":"Bọn trẻ ngắm chim trong công viên.","fa":"بچه ها در پارک به تماشای پرندگان می پردازند."},{"de":"Ich schaue gern zu, wie meine Mutter kocht.","en":"I like watching my mother cook.","ru":"Я люблю смотреть, как моя мама готовит.","vi":"Tôi thích xem mẹ nấu ăn.","fa":"من دوست دارم مادرم را ببینم که آشپزی می کند."}]},{"word":"der Zuschauer","en":"spectator, viewer (male)","ru":"зритель (мужчина)","vi":"khán giả","fa":"تماشاگر","examples":[{"de":"Tausende Zuschauer kamen ins Stadion.","en":"Thousands of spectators came to the stadium.","ru":"Тысячи зрителей пришли на стадион.","vi":"Hàng nghìn khán giả đã đến sân vận động.","fa":"هزاران تماشاگر به ورزشگاه آمدند."},{"de":"Die Zuschauer klatschten begeistert.","en":"The spectators clapped enthusiastically.","ru":"Зрители восторженно хлопали.","vi":"Khán giả vỗ tay nhiệt liệt.","fa":"حضار مشتاقانه دست زدند."},{"de":"Vor dem Fernseher saßen Millionen Zuschauer.","en":"Millions of viewers sat in front of the television.","ru":"Миллионы зрителей сидели у телевизоров.","vi":"Hàng triệu khán giả ngồi trước tivi.","fa":"میلیون ها بیننده جلوی تلویزیون نشستند."}]},{"word":"die Zuschauerin","en":"spectator, viewer (female)","ru":"зрительница (женщина)","vi":"khán giả","fa":"تماشاگر","examples":[{"de":"Die Zuschauerin filmte das Konzert mit dem Handy.","en":"The spectator filmed the concert with her phone.","ru":"Зрительница снимала концерт на телефон.","vi":"Người xem đã quay buổi hòa nhạc bằng điện thoại di động của cô ấy.","fa":"بیننده با تلفن همراه خود از کنسرت فیلم گرفته است."},{"de":"Als Zuschauerin saß sie in der ersten Reihe.","en":"As a spectator she sat in the front row.","ru":"Как зрительница она сидела в первом ряду.","vi":"Với tư cách là khán giả, cô ngồi ở hàng ghế đầu.","fa":"به عنوان یک تماشاگر، او در ردیف اول نشست."},{"de":"Jede Zuschauerin erhielt ein kleines Geschenk.","en":"Each spectator received a small gift.","ru":"Каждая зрительница получила небольшой подарок.","vi":"Mỗi người xem đều nhận được một món quà nhỏ.","fa":"هر بیننده یک هدیه کوچک دریافت کرد."}]},{"word":"der Zuschlag","en":"surcharge","ru":"доплата, надбавка","vi":"phụ phí","fa":"هزینه اضافی","examples":[{"de":"Für den Schnellzug musst du einen Zuschlag zahlen.","en":"You have to pay a surcharge for the express train.","ru":"За скоростной поезд нужно доплатить.","vi":"Bạn phải trả phụ phí cho tàu tốc hành.","fa":"برای قطار سریع السیر باید هزینه اضافی بپردازید."},{"de":"Am Wochenende gibt es einen Zuschlag auf den Preis.","en":"There is a surcharge on the price on weekends.","ru":"По выходным есть надбавка к цене.","vi":"Có một khoản phụ phí vào giá vào cuối tuần.","fa":"در تعطیلات آخر هفته هزینه اضافی برای قیمت وجود دارد."}]},{"word":"der Zustand","en":"condition, state","ru":"состояние","vi":"điều kiện","fa":"شرط","examples":[{"de":"Das Auto ist in einem guten Zustand.","en":"The car is in good condition.","ru":"Машина в хорошем состоянии.","vi":"Chiếc xe đang trong tình trạng tốt.","fa":"ماشین در وضعیت خوبی است."},{"de":"Der Patient befindet sich in einem stabilen Zustand.","en":"The patient is in a stable condition.","ru":"Пациент находится в стабильном состоянии.","vi":"Bệnh nhân đang trong tình trạng ổn định.","fa":"وضعیت بیمار پایدار است."}]},{"word":"zuständig","en":"responsible (for)","ru":"ответственный (за)","vi":"chịu trách nhiệm","fa":"مسئول","examples":[{"de":"Wer ist für diese Abteilung zuständig?","en":"Who is responsible for this department?","ru":"Кто отвечает за этот отдел?","vi":"Ai chịu trách nhiệm về bộ phận này?","fa":"چه کسی مسئول این بخش است؟"},{"de":"Dafür bin ich nicht zuständig.","en":"I am not responsible for that.","ru":"За это я не отвечаю.","vi":"Tôi không chịu trách nhiệm về điều đó.","fa":"من مسئول آن نیستم."}]},{"word":"zustimmen","en":"to agree","ru":"соглашаться","vi":"đồng ý","fa":"موافق","examples":[{"de":"Ich stimme deinem Vorschlag zu.","en":"I agree with your proposal.","ru":"Я согласен с твоим предложением.","vi":"Tôi đồng ý với đề nghị của bạn.","fa":"من با پیشنهاد شما موافقم"},{"de":"Die Eltern müssen dem Ausflug zustimmen.","en":"The parents have to agree to the trip.","ru":"Родители должны согласиться на поездку.","vi":"Cha mẹ phải đồng ý cho chuyến tham quan.","fa":"والدین باید با سفر موافقت کنند."}]},{"word":"die Zustimmung","en":"approval, agreement, consent","ru":"одобрение, согласие","vi":"sự đồng ý","fa":"رضایت","examples":[{"de":"Der Plan fand allgemeine Zustimmung.","en":"The plan met with general approval.","ru":"План встретил всеобщее одобрение.","vi":"Kế hoạch đã được sự đồng thuận chung.","fa":"این طرح با موافقت عمومی روبرو شد."},{"de":"Ohne deine Zustimmung machen wir nichts.","en":"Without your consent we won't do anything.","ru":"Без вашего согласия мы ничего не будем делать.","vi":"Chúng tôi không làm bất cứ điều gì mà không có sự đồng ý của bạn.","fa":"ما هیچ کاری را بدون رضایت شما انجام نمی دهیم."},{"de":"Sie nickte zum Zeichen der Zustimmung.","en":"She nodded as a sign of agreement.","ru":"Она кивнула в знак согласия.","vi":"Cô gật đầu đồng ý.","fa":"سرش را به نشانه موافقت تکان داد."}]},{"word":"die Zutaten","en":"ingredients","ru":"ингредиенты","vi":"các thành phần","fa":"مواد تشکیل دهنده","examples":[{"de":"Welche Zutaten brauchen wir für den Kuchen?","en":"What ingredients do we need for the cake?","ru":"Какие ингредиенты нам нужны для торта?","vi":"Làm bánh chúng ta cần những nguyên liệu gì?","fa":"چه موادی برای کیک لازم داریم؟"},{"de":"Alle Zutaten liegen schon auf dem Tisch.","en":"All the ingredients are already on the table.","ru":"Все ингредиенты уже на столе.","vi":"Tất cả nguyên liệu đã có sẵn trên bàn.","fa":"همه مواد از قبل روی میز هستند."}]},{"word":"die Zutatenliste","en":"list of ingredients","ru":"список ингредиентов, состав","vi":"danh sách các thành phần","fa":"لیست مواد تشکیل دهنده","examples":[{"de":"Lies bitte die Zutatenliste, bevor du das Produkt kaufst.","en":"Please read the list of ingredients before you buy the product.","ru":"Пожалуйста, прочитай состав, прежде чем покупать продукт.","vi":"Vui lòng đọc danh sách thành phần trước khi mua sản phẩm.","fa":"لطفا قبل از خرید محصول لیست مواد تشکیل دهنده را مطالعه کنید."},{"de":"Die Zutatenliste steht auf der Rückseite der Packung.","en":"The list of ingredients is on the back of the packet.","ru":"Список ингредиентов указан на обратной стороне упаковки.","vi":"Danh sách các thành phần nằm ở mặt sau của gói.","fa":"لیست مواد در پشت بسته موجود است."},{"de":"In der Zutatenliste war versteckter Zucker enthalten.","en":"The list of ingredients contained hidden sugar.","ru":"В составе был скрытый сахар.","vi":"Có đường ẩn trong danh sách thành phần.","fa":"قند مخفی در لیست مواد وجود داشت."}]},{"word":"zuverlässig","en":"reliable","ru":"надёжный","vi":"đáng tin cậy","fa":"قابل اعتماد","examples":[{"de":"Mein Kollege ist sehr zuverlässig.","en":"My colleague is very reliable.","ru":"Мой коллега очень надёжный.","vi":"Đồng nghiệp của tôi rất đáng tin cậy.","fa":"همکار من بسیار قابل اعتماد است."},{"de":"Wir suchen einen zuverlässigen Babysitter.","en":"We are looking for a reliable babysitter.","ru":"Мы ищем надёжную няню.","vi":"Chúng tôi đang tìm kiếm một người giữ trẻ đáng tin cậy.","fa":"ما به دنبال یک پرستار کودک مطمئن هستیم."}]},{"word":"die Zuverlässigkeit","en":"reliability, dependability","ru":"надёжность","vi":"độ tin cậy","fa":"قابلیت اطمینان","examples":[{"de":"Auf seine Zuverlässigkeit kann man sich verlassen.","en":"You can rely on his reliability.","ru":"На его надёжность можно положиться.","vi":"Bạn có thể dựa vào độ tin cậy của nó.","fa":"می توانید به قابلیت اطمینان آن اعتماد کنید."},{"de":"Die Zuverlässigkeit der Maschine ist beeindruckend.","en":"The reliability of the machine is impressive.","ru":"Надёжность машины впечатляет.","vi":"Độ tin cậy của máy rất ấn tượng.","fa":"قابلیت اطمینان دستگاه قابل توجه است."},{"de":"Pünktlichkeit und Zuverlässigkeit sind im Job wichtig.","en":"Punctuality and reliability are important on the job.","ru":"На работе важны пунктуальность и надёжность.","vi":"Sự đúng giờ và độ tin cậy là rất quan trọng trong công việc.","fa":"وقت شناسی و قابلیت اطمینان در کار مهم است."}]},{"word":"das Zvieri","en":"afternoon snack (Swiss)","ru":"полдник (швейцарский вариант)","vi":"bữa ăn nhẹ","fa":"میان وعده","examples":[{"de":"Um vier Uhr machen wir ein Zvieri.","en":"At four o'clock we have an afternoon snack.","ru":"В четыре часа у нас полдник.","vi":"Lúc bốn giờ chúng tôi có bữa ăn nhẹ.","fa":"ساعت چهار میان وعده داریم."},{"de":"Zum Zvieri gibt es Kuchen und Tee.","en":"For the afternoon snack there's cake and tea.","ru":"На полдник есть пирог и чай.","vi":"Có bánh và trà để ăn nhẹ.","fa":"کیک و چای برای میان وعده وجود دارد."},{"de":"Die Kinder freuen sich schon auf das Zvieri.","en":"The children are already looking forward to the afternoon snack.","ru":"Дети уже с нетерпением ждут полдника.","vi":"Bọn trẻ đang rất mong chờ giờ ăn nhẹ.","fa":"بچه ها در حال حاضر مشتاقانه منتظر زمان میان وعده هستند."}]},{"word":"zwar","en":"indeed, admittedly","ru":"правда, хотя","vi":"mặc dù","fa":"اگرچه","examples":[{"de":"Er ist zwar müde, aber er arbeitet trotzdem weiter.","en":"He is indeed tired, but he keeps working anyway.","ru":"Он, правда, устал, но всё равно продолжает работать.","vi":"Anh ấy có thể mệt mỏi nhưng vẫn tiếp tục làm việc.","fa":"او ممکن است خسته باشد، اما همچنان به کارش ادامه می دهد."},{"de":"Das Kleid ist zwar teuer, aber sehr schön.","en":"The dress is admittedly expensive, but very beautiful.","ru":"Платье, конечно, дорогое, но очень красивое.","vi":"Chiếc váy đắt tiền nhưng rất đẹp.","fa":"لباس گران است، اما بسیار زیبا است."}]},{"word":"der Zweck","en":"purpose","ru":"цель, назначение","vi":"mục đích","fa":"هدف","examples":[{"de":"Was ist der Zweck dieses Treffens?","en":"What is the purpose of this meeting?","ru":"Какова цель этой встречи?","vi":"Mục đích của cuộc họp này là gì?","fa":"هدف از این جلسه چیست؟"},{"de":"Dieses Gerät dient einem bestimmten Zweck.","en":"This device serves a specific purpose.","ru":"Это устройство служит определённой цели.","vi":"Thiết bị này phục vụ một mục đích cụ thể.","fa":"این دستگاه هدف خاصی را دنبال می کند."}]},{"word":"der Zweifel","en":"doubt","ru":"сомнение","vi":"sự nghi ngờ","fa":"شک","examples":[{"de":"Ich habe keinen Zweifel an seiner Ehrlichkeit.","en":"I have no doubt about his honesty.","ru":"У меня нет сомнений в его честности.","vi":"Tôi không nghi ngờ gì về sự trung thực của anh ấy.","fa":"در صداقتش شک ندارم."},{"de":"Ohne Zweifel ist das die beste Lösung.","en":"Without doubt, this is the best solution.","ru":"Без сомнения, это лучшее решение.","vi":"Không còn nghi ngờ gì nữa, đây là giải pháp tốt nhất.","fa":"بدون شک این بهترین راه حل است."}]},{"word":"zweifeln","en":"to doubt","ru":"сомневаться","vi":"nghi ngờ","fa":"شک","examples":[{"de":"Ich zweifle, ob er die Wahrheit sagt.","en":"I doubt whether he is telling the truth.","ru":"Я сомневаюсь, говорит ли он правду.","vi":"Tôi nghi ngờ liệu anh ấy có nói sự thật hay không.","fa":"من شک دارم که راست می گوید."},{"de":"Sie zweifelt manchmal an sich selbst.","en":"She sometimes doubts herself.","ru":"Она иногда сомневается в себе.","vi":"Đôi khi cô nghi ngờ chính mình.","fa":"او گاهی اوقات به خودش شک می کند."}]},{"word":"die Zweitsprache","en":"second language","ru":"второй язык","vi":"ngôn ngữ thứ hai","fa":"زبان دوم","examples":[{"de":"Für viele Kinder ist Deutsch eine Zweitsprache.","en":"For many children German is a second language.","ru":"Для многих детей немецкий — второй язык.","vi":"Đối với nhiều trẻ em, tiếng Đức là ngôn ngữ thứ hai.","fa":"برای بسیاری از کودکان، آلمانی زبان دوم است."},{"de":"Sie spricht Englisch fast wie eine Zweitsprache.","en":"She speaks English almost like a second language.","ru":"Она говорит по-английски почти как на втором языке.","vi":"Cô ấy nói tiếng Anh gần giống như ngôn ngữ thứ hai.","fa":"او تقریباً مانند زبان دوم انگلیسی صحبت می کند."},{"de":"Eine Zweitsprache lernt man oft im Alltag.","en":"A second language is often learnt in everyday life.","ru":"Второй язык часто учат в повседневной жизни.","vi":"Bạn thường học ngôn ngữ thứ hai trong cuộc sống hàng ngày.","fa":"شما اغلب زبان دوم را در زندگی روزمره یاد می گیرید."}]},{"word":"die Zwiebel","en":"onion","ru":"лук (репчатый)","vi":"củ hành","fa":"پیاز","examples":[{"de":"Für die Suppe brauche ich zwei Zwiebeln.","en":"I need two onions for the soup.","ru":"Для супа мне нужны две луковицы.","vi":"Tôi cần hai củ hành cho món súp.","fa":"برای سوپ دو عدد پیاز لازم دارم."},{"de":"Beim Schneiden der Zwiebel musste ich weinen.","en":"I had to cry while cutting the onion.","ru":"Я плакал, когда резал лук.","vi":"Tôi đã khóc khi cắt hành tây.","fa":"در حین بریدن پیاز گریه کردم."}]},{"word":"zwingen","en":"to force, to compel","ru":"принуждать, заставлять","vi":"lực lượng","fa":"زور","examples":[{"de":"Niemand kann dich zwingen, das zu tun.","en":"No one can force you to do that.","ru":"Никто не может заставить тебя это делать.","vi":"Không ai có thể buộc bạn làm điều đó.","fa":"هیچ کس نمی تواند شما را مجبور به انجام این کار کند."},{"de":"Der Regen zwang uns, drinnen zu bleiben.","en":"The rain forced us to stay indoors.","ru":"Дождь вынудил нас остаться дома.","vi":"Mưa buộc chúng tôi phải ở trong nhà.","fa":"باران مجبور شد در خانه بمانیم."},{"de":"Man sollte Kinder nicht zum Essen zwingen.","en":"You shouldn't force children to eat.","ru":"Не стоит заставлять детей есть.","vi":"Không nên ép trẻ ăn.","fa":"کودکان را نباید مجبور به غذا خوردن کرد."}]},{"word":"zwischen","en":"between","ru":"между","vi":"giữa","fa":"بین","examples":[{"de":"Das Café liegt zwischen der Bank und der Post.","en":"The café is located between the bank and the post office.","ru":"Кафе находится между банком и почтой.","vi":"Quán cà phê nằm giữa ngân hàng và bưu điện.","fa":"کافه بین بانک و اداره پست قرار دارد."},{"de":"Zwischen den beiden Ländern gibt es gute Beziehungen.","en":"There are good relations between the two countries.","ru":"Между этими двумя странами хорошие отношения.","vi":"Có mối quan hệ tốt đẹp giữa hai nước.","fa":"روابط خوبی بین دو کشور وجود دارد."}]},{"word":"der Zwischenfall","en":"incident","ru":"происшествие, инцидент","vi":"sự việc","fa":"واقعه","examples":[{"de":"Während der Reise gab es keinen Zwischenfall.","en":"There was no incident during the trip.","ru":"Во время поездки не было ни одного происшествия.","vi":"Không có sự cố nào xảy ra trong chuyến đi.","fa":"در طول سفر هیچ حادثه ای رخ نداد."},{"de":"Der Flug verlief ohne besonderen Zwischenfall.","en":"The flight passed without any particular incident.","ru":"Полёт прошёл без особых происшествий.","vi":"Chuyến bay đã diễn ra mà không có bất kỳ sự cố cụ thể nào.","fa":"پرواز بدون حادثه خاصی انجام شد."},{"de":"Nach dem Zwischenfall rief man die Polizei.","en":"After the incident the police were called.","ru":"После инцидента вызвали полицию.","vi":"Sau khi vụ việc xảy ra, cảnh sát đã được gọi đến.","fa":"پس از این حادثه با پلیس تماس گرفته شد."}]},{"word":"die Zwischenmahlzeit","en":"snack between meals","ru":"перекус между приёмами пищи","vi":"bữa ăn nhẹ","fa":"میان وعده","examples":[{"de":"Eine gesunde Zwischenmahlzeit hält dich fit.","en":"A healthy snack between meals keeps you fit.","ru":"Здоровый перекус поддерживает форму.","vi":"Một bữa ăn nhẹ lành mạnh giúp bạn giữ dáng.","fa":"یک میان وعده سالم شما را تناسب اندام نگه می دارد."},{"de":"Als Zwischenmahlzeit esse ich gern einen Apfel.","en":"For a snack between meals I like to eat an apple.","ru":"В качестве перекуса я люблю есть яблоко.","vi":"Tôi thích ăn một quả táo như một món ăn nhẹ.","fa":"من دوست دارم یک سیب را به عنوان میان وعده بخورم."},{"de":"Kinder brauchen oft eine kleine Zwischenmahlzeit.","en":"Children often need a small snack between meals.","ru":"Детям часто нужен небольшой перекус между приёмами пищи.","vi":"Trẻ em thường cần một bữa ăn nhẹ nhỏ.","fa":"کودکان اغلب به یک میان وعده کوچک نیاز دارند."}]}];
